window.bibleReaderData = {"meta":{"phase":"new-testament","source":{"fa":"ترجمه قدیم فارسی / Old Persian Version — eBible/BibleNLP","en":"World English Bible Protestant Edition — eBible/BibleNLP","hr":"Sveta Biblija / Ivan Šarić — eBible/BibleNLP"},"note":{"fa":"تمام کتاب‌های عهد جدید در این بخش قرار گرفته است. توضیح کلمات کلیدی از زبان اصلی به‌تدریج تکمیل می‌شود.","en":"All New Testament books are included in this section. Original-language key word explanations will be expanded progressively.","hr":"Sve knjige Novoga zavjeta uključene su u ovaj odjeljak. Objašnjenja ključnih riječi iz izvornog jezika postupno će se proširivati."}},"books":[{"id":"MAT","fa":"متی","en":"Matthew","hr":"Matej","chapters":28},{"id":"MRK","fa":"مرقس","en":"Mark","hr":"Marko","chapters":16},{"id":"LUK","fa":"لوقا","en":"Luke","hr":"Luka","chapters":24},{"id":"JHN","fa":"یوحنا","en":"John","hr":"Ivan","chapters":21},{"id":"ACT","fa":"اعمال رسولان","en":"Acts","hr":"Djela apostolska","chapters":28},{"id":"ROM","fa":"رومیان","en":"Romans","hr":"Rimljanima","chapters":16},{"id":"1CO","fa":"اول قرنتیان","en":"1 Corinthians","hr":"1. Korinćanima","chapters":16},{"id":"2CO","fa":"دوم قرنتیان","en":"2 Corinthians","hr":"2. Korinćanima","chapters":13},{"id":"GAL","fa":"غلاطیان","en":"Galatians","hr":"Galaćanima","chapters":6},{"id":"EPH","fa":"افسسیان","en":"Ephesians","hr":"Efežanima","chapters":6},{"id":"PHP","fa":"فیلیپیان","en":"Philippians","hr":"Filipljanima","chapters":4},{"id":"COL","fa":"کولسیان","en":"Colossians","hr":"Kološanima","chapters":4},{"id":"1TH","fa":"اول تسالونیکیان","en":"1 Thessalonians","hr":"1. Solunjanima","chapters":5},{"id":"2TH","fa":"دوم تسالونیکیان","en":"2 Thessalonians","hr":"2. Solunjanima","chapters":3},{"id":"1TI","fa":"اول تیموتائوس","en":"1 Timothy","hr":"1. Timoteju","chapters":6},{"id":"2TI","fa":"دوم تیموتائوس","en":"2 Timothy","hr":"2. Timoteju","chapters":4},{"id":"TIT","fa":"تیطس","en":"Titus","hr":"Titu","chapters":3},{"id":"PHM","fa":"فیلیمون","en":"Philemon","hr":"Filemonu","chapters":1},{"id":"HEB","fa":"عبرانیان","en":"Hebrews","hr":"Hebrejima","chapters":13},{"id":"JAS","fa":"یعقوب","en":"James","hr":"Jakovljeva","chapters":5},{"id":"1PE","fa":"اول پطرس","en":"1 Peter","hr":"1. Petrova","chapters":5},{"id":"2PE","fa":"دوم پطرس","en":"2 Peter","hr":"2. Petrova","chapters":3},{"id":"1JN","fa":"اول یوحنا","en":"1 John","hr":"1. Ivanova","chapters":5},{"id":"2JN","fa":"دوم یوحنا","en":"2 John","hr":"2. Ivanova","chapters":1},{"id":"3JN","fa":"سوم یوحنا","en":"3 John","hr":"3. Ivanova","chapters":1},{"id":"JUD","fa":"یهودا","en":"Jude","hr":"Judina","chapters":1},{"id":"REV","fa":"مکاشفه","en":"Revelation","hr":"Otkrivenje","chapters":22}],"chapters":{"MAT":{"1":{"fa":[{"v":1,"t":"کتاب نسب نامه عیسی مسیح بن داود بن ابراهیم:"},{"v":2,"t":"ابراهیم اسحاق را آورد و اسحاق یعقوب را آورد و یعقوب یهودا و برادران او راآورد."},{"v":3,"t":"و یهودا، فارص و زارح را از تامار آورد وفارص، حصرون را آورد و حصرون، ارام را آورد."},{"v":4,"t":"و ارام، عمیناداب را آورد و عمیناداب، نحشون را آورد و نحشون، شلمون را آورد."},{"v":5,"t":"وشلمون، بوعز را از راحاب آورد و بوعز، عوبیدرا از راعوت آورد و عوبید، یسا را آورد."},{"v":6,"t":"ویسا داود پادشاه را آورد و داود پادشاه، سلیمان را از زن اوریا آورد."},{"v":7,"t":"و سلیمان، رحبعام را آورد و رحبعام، ابیا را آورد و ابیا، آسا راآورد."},{"v":8,"t":"و آسا، یهوشافاط را آورد و یهوشافاط، یورام را آورد و یورام، عزیا را آورد."},{"v":9,"t":"و عزیا، یوتام را آورد و یوتام، احاز را آورد و احاز، حزقیا را آورد."},{"v":10,"t":"و حزقیا، منسی را آورد ومنسی، آمون را آورد و آمون، یوشیا را آورد."},{"v":11,"t":"ویوشیا، یکنیا و برادرانش را در زمان جلای بابل آورد."},{"v":12,"t":"و بعد از جلای بابل، یکنیا، سالتیئل را آورد و سالتیئیل، زروبابل را آورد."},{"v":13,"t":"زروبابل، ابیهود را آورد و ابیهود، ایلیقایم را آورد و ایلیقایم، عازور را آورد."},{"v":14,"t":"و عازور، صادوق را آورد و صادوق، یاکین را آورد و یاکین، ایلیهود را آورد."},{"v":15,"t":"و ایلیهود، ایلعازر را آوردو ایلعازر، متان را آورد و متان، یعقوب راآورد."},{"v":16,"t":"و یعقوب، یوسف شوهر مریم راآورد که عیسی مسمی به مسیح از او متولدشد."},{"v":17,"t":"پس تمام طبقات، از ابراهیم تا داودچهارده طبقه است، و از داود تا جلای بابل چهارده طبقه، و از جلای بابل تا مسیح چهارده طبقه."},{"v":18,"t":"اما ولادت عیسی مسیح چنین بود که چون مادرش مریم به یوسف نامزد شده بود، قبل ازآنکه با هم آیند، او را از روح‌القدس حامله یافتند."},{"v":19,"t":"و شوهرش یوسف چونکه مرد صالح بود ونخواست او را عبرت نماید، پس اراده نمود او رابه پنهانی رها کند."},{"v":20,"t":"اما چون او در این چیزهاتفکر می‌کرد، ناگاه فرشته خداوند در خواب بروی ظاهر شده، گفت: «ای یوسف پسر داود، ازگرفتن زن خویش مریم مترس، زیرا که آنچه دروی قرار گرفته است، از روح‌القدس است،"},{"v":21,"t":"و اوپسری خواهد زایید و نام او را عیسی خواهی نهاد، زیرا که او امت خویش را از گناهانشان خواهد رهانید.»"},{"v":22,"t":"و این همه برای آن واقع شد تاکلامی که خداوند به زبان نبی گفته بود، تمام گردد"},{"v":23,"t":"«که اینک باکره آبستن شده پسری خواهدزایید و نام او را عمانوئیل خواهند خواند که تفسیرش این است: خدا با ما.»"},{"v":24,"t":"پس چون یوسف از خواب بیدار شد، چنانکه فرشته خداوند بدو امر کرده بود، بعمل آورد و زن خویش را گرفت"},{"v":25,"t":"و تا پسر نخستین خود رانزایید، او را نشناخت؛ و او را عیسی نام نهاد."}],"en":[{"v":1,"t":"The book of the genealogy of Jesus Christ, the son of David, the son of Abraham."},{"v":2,"t":"Abraham became the father of Isaac. Isaac became the father of Jacob. Jacob became the father of Judah and his brothers."},{"v":3,"t":"Judah became the father of Perez and Zerah by Tamar. Perez became the father of Hezron. Hezron became the father of Ram."},{"v":4,"t":"Ram became the father of Amminadab. Amminadab became the father of Nahshon. Nahshon became the father of Salmon."},{"v":5,"t":"Salmon became the father of Boaz by Rahab. Boaz became the father of Obed by Ruth. Obed became the father of Jesse."},{"v":6,"t":"Jesse became the father of King David. David the king became the father of Solomon by her who had been Uriah’s wife."},{"v":7,"t":"Solomon became the father of Rehoboam. Rehoboam became the father of Abijah. Abijah became the father of Asa."},{"v":8,"t":"Asa became the father of Jehoshaphat. Jehoshaphat became the father of Joram. Joram became the father of Uzziah."},{"v":9,"t":"Uzziah became the father of Jotham. Jotham became the father of Ahaz. Ahaz became the father of Hezekiah."},{"v":10,"t":"Hezekiah became the father of Manasseh. Manasseh became the father of Amon. Amon became the father of Josiah."},{"v":11,"t":"Josiah became the father of Jechoniah and his brothers at the time of the exile to Babylon."},{"v":12,"t":"After the exile to Babylon, Jechoniah became the father of Shealtiel. Shealtiel became the father of Zerubbabel."},{"v":13,"t":"Zerubbabel became the father of Abiud. Abiud became the father of Eliakim. Eliakim became the father of Azor."},{"v":14,"t":"Azor became the father of Zadok. Zadok became the father of Achim. Achim became the father of Eliud."},{"v":15,"t":"Eliud became the father of Eleazar. Eleazar became the father of Matthan. Matthan became the father of Jacob."},{"v":16,"t":"Jacob became the father of Joseph, the husband of Mary, from whom was born Jesus, who is called Christ."},{"v":17,"t":"So all the generations from Abraham to David are fourteen generations; from David to the exile to Babylon fourteen generations; and from the carrying away to Babylon to the Christ, fourteen generations."},{"v":18,"t":"Now the birth of Jesus Christ was like this: After his mother, Mary, was engaged to Joseph, before they came together, she was found pregnant by the Holy Spirit."},{"v":19,"t":"Joseph, her husband, being a righteous man, and not willing to make her a public example, intended to put her away secretly."},{"v":20,"t":"But when he thought about these things, behold, an angel of the Lord appeared to him in a dream, saying, “Joseph, son of David, don’t be afraid to take to yourself Mary as your wife, for that which is conceived in her is of the Holy Spirit."},{"v":21,"t":"She shall give birth to a son. You shall name him Jesus, for it is he who shall save his people from their sins.”"},{"v":22,"t":"Now all this has happened that it might be fulfilled which was spoken by the Lord through the prophet, saying,"},{"v":23,"t":"“Behold, the virgin shall be with child, and shall give birth to a son. They shall call his name Immanuel,” which is, being interpreted, “God with us.”"},{"v":24,"t":"Joseph arose from his sleep, and did as the angel of the Lord commanded him, and took his wife to himself;"},{"v":25,"t":"and didn’t know her sexually until she had given birth to her firstborn son. He named him Jesus."}],"hr":[{"v":1,"t":"Rodoslovlje Isusa Krista, sina Davidova, sina Abrahamova."},{"v":2,"t":"Abrahamu se rodi Izak. Izaku se rodi Jakov. Jakovu se rodi Juda i njegova braća."},{"v":3,"t":"Judi Tamara rodi Peresa i Zeraha. Peresu se rodi Hesron. Hesronu se rodi Ram."},{"v":4,"t":"Ramu se rodi Aminadab. Aminadabu se rodi Nahšon. Nahšonu se rodi Salma."},{"v":5,"t":"Salmi Rahaba rodi Boaza. Boazu Ruta rodi Obeda. Obedu se rodi Jišaj."},{"v":6,"t":"Jišaju se rodi David kralj. Davidu bivša žena Urijina rodi Salomona."},{"v":7,"t":"Salomonu se rodi Roboam. Roboamu se rodi Abija. Abiji se rodi Asa."},{"v":8,"t":"Asi se rodi Jozafat. Jozafatu se rodi Joram. Joramu se rodi Ahazja."},{"v":9,"t":"Ahazji se rodi Jotam. Jotamu se rodi Ahaz. Ahazu se rodi Ezekija."},{"v":10,"t":"Ezekiji se rodi Manaše. Manašeu se rodi Amon. Amonu se rodi Jošija."},{"v":11,"t":"Jošiji se rodi Jehonija i njegova braća u vrijeme progonstva u Babilon."},{"v":12,"t":"Poslije progonstva u Babilon Jehoniji se rodi Šealtiel. Šealtielu se rodi Zerubabel."},{"v":13,"t":"Zerubabelu se rodi Abiud. Abiudu se rodi Elijakim. Elijakimu se rodi Azor."},{"v":14,"t":"Azoru se rodi Sadok. Sadoku se rodi Akim. Akimu se rodi Elijud."},{"v":15,"t":"Elijudu se rodi Eleazar. Eleazaru se rodi Matan. Matanu se rodi Jakov."},{"v":16,"t":"Jakovu se rodi Josip, muž Marije, od koje se rodio Isus koji se zove Krist."},{"v":17,"t":"U svemu dakle: od Abrahama do Davida četrnaest naraštaja; od Davida do progonstva u Babilon četrnaest naraštaja; poslije progonstva u Babilon do Krista četrnaest naraštaja."},{"v":18,"t":"A rođenje Isusa Krista zbilo se ovako. Njegova majka Marija, zaručena s Josipom, prije nego se sastadoše, nađe se trudna po Duhu Svetom."},{"v":19,"t":"A Josip, muž njezin, pravedan, ne htjede je izvrgnuti sramoti, nego naumi da je potajice napusti."},{"v":20,"t":"Dok je on to snovao, gle, anđeo mu se Gospodnji ukaza u snu i reče: “Josipe, sine Davidov, ne boj se uzeti k sebi Mariju, ženu svoju. Što je u njoj začeto, doista je od Duha Svetoga."},{"v":21,"t":"Rodit će sina, a ti ćeš mu nadjenuti ime Isus jer će on spasiti narod svoj od grijeha njegovih.”"},{"v":22,"t":"Sve se to dogodilo da se ispuni što Gospodin reče po proroku:"},{"v":23,"t":"Evo, Djevica će začeti i roditi sina i nadjenut će mu se ime Emanuel - što znači: S nama Bog!"},{"v":24,"t":"Kad se Josip probudi oda sna, učini kako mu naredi anđeo Gospodnji: uze k sebi svoju ženu."},{"v":25,"t":"I ne upozna je dok ne rodi sina. I nadjenu mu ime Isus."}]},"2":{"fa":[{"v":1,"t":"و چون عیسی در ایام هیرودیس پادشاه دربیت لحم یهودیه تولد یافت، ناگاه مجوسی چند از مشرق به اورشلیم آمده، گفتند:"},{"v":2,"t":"«کجاست آن مولود که پادشاه یهود است زیراکه ستاره او را در مشرق دیده‌ایم و برای پرستش او آمده‌ایم؟»"},{"v":3,"t":"اما هیرودیس پادشاه چون این راشنید، مضطرب شد و تمام اورشلیم با وی."},{"v":4,"t":"پس همه روسای کهنه و کاتبان قوم را جمع کرده، ازایشان پرسید که «مسیح کجا باید متولد شود؟»"},{"v":5,"t":"بدو گفتند: «در بیت لحم یهودیه زیرا که از نبی چنین مکتوب است:"},{"v":6,"t":"و تو‌ای بیت لحم، در زمین یهودا از سایر سرداران یهودا هرگز کوچکترنیستی، زیرا که از تو پیشوایی به ظهور خواهدآمد که قوم من اسرائیل را رعایت خواهد نمود.»"},{"v":7,"t":"آنگاه هیرودیس مجوسیان را در خلوت خوانده، وقت ظهور ستاره را از ایشان تحقیق کرد."},{"v":8,"t":"پس ایشان را به بیت لحم روانه نموده، گفت: «بروید و از احوال آن طفل بتدقیق تفحص کنید و چون یافتید مرا خبر دهید تا من نیز آمده، او را پرستش نمایم.»"},{"v":9,"t":"چون سخن پادشاه راشنیدند، روانه شدند که ناگاه آن ستاره‌ای که در مشرق دیده بودند، پیش روی ایشان می‌رفت تافوق آنجایی که طفل بود رسیده، بایستاد."},{"v":10,"t":"وچون ستاره را دیدند، بی‌نهایت شاد و خوشحال گشتند"},{"v":11,"t":"و به خانه درآمده، طفل را با مادرش مریم یافتند و به روی در‌افتاده، او را پرستش کردند و ذخایر خود را گشوده، هدایای طلا وکندر و مر به وی گذرانیدند."},{"v":12,"t":"و چون در خواب وحی بدیشان در‌رسید که به نزد هیرودیس بازگشت نکنند، پس از راه دیگر به وطن خویش مراجعت کردند."},{"v":13,"t":"و چون ایشان روانه شدند، ناگاه فرشته خداوند در خواب به یوسف ظاهر شده، گفت: «برخیز و طفل و مادرش را برداشته به مصر فرارکن و در آنجا باش تا به تو خبر دهم، زیرا که هیرودیس طفل را جستجو خواهد کرد تا او راهلاک نماید.»"},{"v":14,"t":"پس شبانگاه برخاسته، طفل ومادر او را برداشته، بسوی مصر روانه شد"},{"v":15,"t":"و تاوفات هیرودیس در آنجا بماند، تا کلامی که خداوند به زبان نبی گفته بود تمام گردد که «ازمصر پسر خود را خواندم.»"},{"v":16,"t":"چون هیرودیس دید که مجوسیان او را سخریه نموده‌اند، بسیارغضبناک شده، فرستاد و جمیع اطفالی را که دربیت لحم و تمام نواحی آن بودند، از دو ساله وکمتر موافق وقتی که از مجوسیان تحقیق نموده بود، به قتل رسانید."},{"v":17,"t":"آنگاه کلامی که به زبان ارمیای نبی گفته شده بود، تمام شد: «آوازی دررامه شنیده شد، گریه و زاری و ماتم عظیم که راحیل برای فرزندان خود گریه می‌کند و تسلی نمی پذیرد زیرا که نیستند.»"},{"v":18,"t":"اما چون هیرودیس وفات یافت، ناگاه فرشته خداوند در مصر به یوسف در خواب ظاهرشده، گفت:"},{"v":19,"t":"«برخیز و طفل و مادرش رابرداشته، به زمین اسرائیل روانه شو زیرا آنانی که قصد جان طفل داشتند فوت شدند.»"},{"v":20,"t":"پس برخاسته، طفل و مادر او را برداشت و به زمین اسرائیل آمد."},{"v":21,"t":"اما چون شنید که ارکلاوس به‌جای پدر خود هیرودیس بر یهودیه پادشاهی می‌کند، از رفتن بدان سمت ترسید و در خواب وحی یافته، به نواحی جلیل برگشت."},{"v":22,"t":"و آمده در بلده‌ای مسمی به ناصره ساکن شد، تا آنچه به زبان انبیا گفته شده بود تمام شود که «به ناصری خوانده خواهد شد.»"}],"en":[{"v":1,"t":"Now when Jesus was born in Bethlehem of Judea in the days of King Herod, behold, wise men from the east came to Jerusalem, saying,"},{"v":2,"t":"“Where is he who is born King of the Jews? For we saw his star in the east, and have come to worship him.”"},{"v":3,"t":"When King Herod heard it, he was troubled, and all Jerusalem with him."},{"v":4,"t":"Gathering together all the chief priests and scribes of the people, he asked them where the Christ would be born."},{"v":5,"t":"They said to him, “In Bethlehem of Judea, for this is written through the prophet,"},{"v":6,"t":"‘You Bethlehem, land of Judah, are in no way least among the princes of Judah; for out of you shall come a governor who shall shepherd my people, Israel.’”"},{"v":7,"t":"Then Herod secretly called the wise men, and learned from them exactly what time the star appeared."},{"v":8,"t":"He sent them to Bethlehem, and said, “Go and search diligently for the young child. When you have found him, bring me word, so that I also may come and worship him.”"},{"v":9,"t":"They, having heard the king, went their way; and behold, the star, which they saw in the east, went before them until it came and stood over where the young child was."},{"v":10,"t":"When they saw the star, they rejoiced with exceedingly great joy."},{"v":11,"t":"They came into the house and saw the young child with Mary, his mother, and they fell down and worshiped him. Opening their treasures, they offered to him gifts: gold, frankincense, and myrrh."},{"v":12,"t":"Being warned in a dream not to return to Herod, they went back to their own country another way."},{"v":13,"t":"Now when they had departed, behold, an angel of the Lord appeared to Joseph in a dream, saying, “Arise and take the young child and his mother, and flee into Egypt, and stay there until I tell you, for Herod will seek the young child to destroy him.”"},{"v":14,"t":"He arose and took the young child and his mother by night and departed into Egypt,"},{"v":15,"t":"and was there until the death of Herod, that it might be fulfilled which was spoken by the Lord through the prophet, saying, “Out of Egypt I called my son.”"},{"v":16,"t":"Then Herod, when he saw that he was mocked by the wise men, was exceedingly angry, and sent out and killed all the male children who were in Bethlehem and in all the surrounding countryside, from two years old and under, according to the exact time which he had learned from the wise men."},{"v":17,"t":"Then that which was spoken by Jeremiah the prophet was fulfilled, saying,"},{"v":18,"t":"“A voice was heard in Ramah, lamentation, weeping and great mourning, Rachel weeping for her children; she wouldn’t be comforted, because they are no more.”"},{"v":19,"t":"But when Herod was dead, behold, an angel of the Lord appeared in a dream to Joseph in Egypt, saying,"},{"v":20,"t":"“Arise and take the young child and his mother, and go into the land of Israel, for those who sought the young child’s life are dead.”"},{"v":21,"t":"He arose and took the young child and his mother, and came into the land of Israel."},{"v":22,"t":"But when he heard that Archelaus was reigning over Judea in the place of his father, Herod, he was afraid to go there. Being warned in a dream, he withdrew into the region of Galilee,"},{"v":23,"t":"and came and lived in a city called Nazareth; that it might be fulfilled which was spoken through the prophets that he will be called a Nazarene."}],"hr":[{"v":1,"t":"Kad se Isus rodio u Betlehemu judejskome u dane Heroda kralja, gle, mudraci se s Istoka pojaviše u Jeruzalemu"},{"v":2,"t":"raspitujući se: “Gdje je taj novorođeni kralj židovski? Vidjesmo gdje izlazi zvijezda njegova pa mu se dođosmo pokloniti.”"},{"v":3,"t":"Kada to doču kralj Herod, uznemiri se on i sav Jeruzalem s njime."},{"v":4,"t":"Sazva sve glavare svećeničke i pismoznance narodne pa ih ispitivaše gdje se Krist ima roditi."},{"v":5,"t":"Oni mu odgovoriše: “U Betlehemu judejskome jer ovako piše prorok:"},{"v":6,"t":"A ti, Betleheme, zemljo Judina! Nipošto nisi najmanji među kneževstvima Judinim jer iz tebe će izaći vladalac koji će pasti narod moj - Izraela!"},{"v":7,"t":"Tada Herod potajno dozva mudrace i razazna od njih vrijeme kad se pojavila zvijezda."},{"v":8,"t":"Zatim ih posla u Betlehem: “Pođite, reče, i pomno se raspitajte za dijete. Kad ga nađete, javite mi da i ja pođem te mu se poklonim.”"},{"v":9,"t":"Oni saslušavši kralja, pođoše. I gle, zvijezda kojoj vidješe izlazak iđaše pred njima sve dok ne stiže i zaustavi se povrh mjesta gdje bijaše dijete."},{"v":10,"t":"Kad ugledaše zvijezdu, obradovaše se radošću veoma velikom."},{"v":11,"t":"Uđu u kuću, ugledaju dijete s Marijom, majkom njegovom, padnu ničice i poklone mu se. Otvore zatim svoje blago i prinesu mu darove: zlato, tamjan i smirnu."},{"v":12,"t":"Upućeni zatim u snu da se ne vraćaju Herodu, otiđoše drugim putem u svoju zemlju."},{"v":13,"t":"A pošto oni otiđoše, gle, anđeo se Gospodnji u snu javi Josipu: “Ustani, reče, uzmi dijete i majku njegovu te bježi u Egipat i ostani ondje dok ti ne reknem jer će Herod tražiti dijete da ga pogubi."},{"v":14,"t":"On ustane, uzme noću dijete i majku njegovu te krene u Egipat."},{"v":15,"t":"I osta ondje do Herodova skončanja - da se ispuni što Gospodin reče po proroku: Iz Egipta dozvah Sina svoga."},{"v":16,"t":"Vidjevši da su ga mudraci izigrali, Herod se silno rasrdi i posla poubijati sve dječake u Betlehemu i po svoj okolici, od dvije godine naniže - prema vremenu što ga razazna od mudraca."},{"v":17,"t":"Tada se ispuni što je rečeno po proroku Jeremiji:"},{"v":18,"t":"U Rami se glas čuje, kuknjava i plač gorak: Rahela oplakuje sinove svoje i neće da se utješi jer više ih nema."},{"v":19,"t":"Nakon Herodova skončanja, gle, anđeo se Gospodnji javi u snu Josipu u Egiptu:"},{"v":20,"t":"“Ustani, reče, uzmi dijete i njegovu majku te pođi u zemlju izraelsku jer su umrli oni koji su djetetu o glavi radili.”"},{"v":21,"t":"On ustane, uzme dijete i njegovu majku te uđe u zemlju izraelsku."},{"v":22,"t":"Ali saznavši da Arhelaj vlada Judejom namjesto svoga oca Heroda, bojao se poći onamo pa, upućen u snu, ode u kraj galilejski."},{"v":23,"t":"Dođe i nastani se u gradu zvanu Nazaret - da se ispuni što je rečeno po prorocima: Zvat će se Nazarećanin."}]},"3":{"fa":[{"v":1,"t":"و در آن ایام، یحیی تعمید‌دهنده در بیابان یهودیه ظاهر شد و موعظه کرده، می‌گفت:"},{"v":2,"t":"«توبه کنید، زیرا ملکوت آسمان نزدیک است.»"},{"v":3,"t":"زیرا همین است آنکه اشعیای نبی از او خبرداده، می‌گوید: «صدای ندا کننده‌ای در بیابان که راه خداوند را مهیا سازید و طرق او را راست نمایید.»"},{"v":4,"t":"و این یحیی لباس از پشم شترمی داشت، و کمربند چرمی بر کمر و خوراک او ازملخ و عسل بری می‌بود."},{"v":5,"t":"در این وقت، اورشلیم و تمام یهودیه وجمیع حوالی اردن نزد او بیرون می‌آمدند،"},{"v":6,"t":"و به گناهان خود اعتراف کرده، در اردن از وی تعمیدمی یافتند."},{"v":7,"t":"پس چون بسیاری از فریسیان و صدوقیان رادید که بجهت تعمید وی می‌آیند، بدیشان گفت: «ای افعی‌زادگان، که شما را اعلام کرد که از غضب آینده بگریزید؟"},{"v":8,"t":"اکنون ثمره شایسته توبه بیاورید،"},{"v":9,"t":"و این سخن را به‌خاطر خود راه مدهیدکه پدر ما ابراهیم است، زیرا به شما می‌گویم خداقادر است که از این سنگها فرزندان برای ابراهیم برانگیزاند."},{"v":10,"t":"و الحال تیشه بر ریشه درختان نهاده شده است، پس هر درختی که ثمره نیکونیاورد، بریده و در آتش افکنده شود."},{"v":11,"t":"من شمارا به آب به جهت توبه تعمید می‌دهم. لکن او که بعد از من می‌آید از من تواناتر است که لایق برداشتن نعلین او نیستم؛ او شما را به روح‌القدس و آتش تعمید خواهد داد."},{"v":12,"t":"او غربال خود را دردست دارد و خرمن خود را نیکو پاک کرده، گندم خویش را در انبار ذخیره خواهد نمود، ولی کاه رادر آتشی که خاموشی نمی پذیرد خواهدسوزانید.»"},{"v":13,"t":"آنگاه عیسی از جلیل به اردن نزد یحیی آمدتا از او تعمید یابد."},{"v":14,"t":"اما یحیی او را منع نموده، گفت: «من احتیاج دارم که از تو تعمید یابم و تونزد من می‌آیی؟»"},{"v":15,"t":"عیسی در جواب وی گفت: «الان بگذارزیرا که ما را همچنین مناسب است تا تمام عدالت را به‌کمال رسانیم.»"},{"v":16,"t":"اما عیسی چون تعمیدیافت، فور از آب برآمد که در ساعت آسمان بروی گشاده شد و روح خدا را دید که مثل کبوتری نزول کرده، بر وی می‌آید."},{"v":17,"t":"آنگاه خطابی ازآسمان در‌رسید که «این است پسر حبیب من که ازاو خشنودم.»"}],"en":[{"v":1,"t":"In those days, John the Baptizer came, preaching in the wilderness of Judea, saying,"},{"v":2,"t":"“Repent, for the Kingdom of Heaven is at hand!”"},{"v":3,"t":"For this is he who was spoken of by Isaiah the prophet, saying, “The voice of one crying in the wilderness, make the way of the Lord ready! Make his paths straight!”"},{"v":4,"t":"Now John himself wore clothing made of camel’s hair with a leather belt around his waist. His food was locusts and wild honey."},{"v":5,"t":"Then people from Jerusalem, all of Judea, and all the region around the Jordan went out to him."},{"v":6,"t":"They were baptized by him in the Jordan, confessing their sins."},{"v":7,"t":"But when he saw many of the Pharisees and Sadducees coming for his baptism, he said to them, “You offspring of vipers, who warned you to flee from the wrath to come?"},{"v":8,"t":"Therefore produce fruit worthy of repentance!"},{"v":9,"t":"Don’t think to yourselves, ‘We have Abraham for our father,’ for I tell you that God is able to raise up children to Abraham from these stones."},{"v":10,"t":"Even now the ax lies at the root of the trees. Therefore every tree that doesn’t produce good fruit is cut down, and cast into the fire."},{"v":11,"t":"“I indeed baptize you in water for repentance, but he who comes after me is mightier than I, whose sandals I am not worthy to carry. He will baptize you in the Holy Spirit."},{"v":12,"t":"His winnowing fork is in his hand, and he will thoroughly cleanse his threshing floor. He will gather his wheat into the barn, but the chaff he will burn up with unquenchable fire.”"},{"v":13,"t":"Then Jesus came from Galilee to the Jordan to John, to be baptized by him."},{"v":14,"t":"But John would have hindered him, saying, “I need to be baptized by you, and you come to me?”"},{"v":15,"t":"But Jesus, answering, said to him, “Allow it now, for this is the fitting way for us to fulfill all righteousness.” Then he allowed him."},{"v":16,"t":"Jesus, when he was baptized, went up directly from the water: and behold, the heavens were opened to him. He saw the Spirit of God descending as a dove, and coming on him."},{"v":17,"t":"Behold, a voice out of the heavens said, “This is my beloved Son, with whom I am well pleased.”"}],"hr":[{"v":1,"t":"U one dane pojavi se Ivan Krstitelj propovijedajući u Judejskoj pustinji:"},{"v":2,"t":"“Obratite se jer približilo se kraljevstvo nebesko!”"},{"v":3,"t":"Ovo je uistinu onaj o kom proreče Izaija prorok: Glas viče u pustinji: Pripravite put Gospodinu, poravnite mu staze!"},{"v":4,"t":"Ivan je imao odjeću od devine dlake i kožnat pojas oko bokova; hranom mu bijahu skakavci i divlji med."},{"v":5,"t":"Grnuo k njemu Jeruzalem, sva Judeja i sva okolica jordanska."},{"v":6,"t":"Primali su od njega krštenje u rijeci Jordanu ispovijedajući svoje grijehe."},{"v":7,"t":"Kad ugleda mnoge farizeje i saduceje gdje mu dolaze na krštenje, reče im: “Leglo gujinje! Tko li vas je samo upozorio da bježite od skore srdžbe?"},{"v":8,"t":"Donosite dakle plod dostojan obraćenja."},{"v":9,"t":"I ne usudite se govoriti u sebi: 'Imamo oca Abrahama!' Jer, kažem vam, Bog iz ovoga kamenja može podići djecu Abrahamovu."},{"v":10,"t":"Već je sjekira položena na korijen stablima. Svako dakle stablo koje ne donosi dobroga roda, siječe se i u oganj baca.”"},{"v":11,"t":"“Ja vas, istina, krstim vodom na obraćenje, ali onaj koji za mnom dolazi jači je od mene. Ja nisam dostojan obuće mu nositi. On će vas krstiti Duhom Svetim i ognjem."},{"v":12,"t":"U ruci mu vijača, pročistit će svoje gumno i skupiti žito u svoju žitnicu, a pljevu spaliti ognjem neugasivim.”"},{"v":13,"t":"Tada dođe Isus iz Galileje na Jordan Ivanu da ga on krsti."},{"v":14,"t":"Ivan ga odvraćaše: “Ti mene treba da krstiš, a ti da k meni dolaziš?”"},{"v":15,"t":"Ali mu Isus odgovori: “Pusti sada! Ta dolikuje nam da tako ispunimo svu pravednost!” Tada mu popusti."},{"v":16,"t":"Odmah nakon krštenja izađe Isus iz vode. I gle! Otvoriše se nebesa i ugleda Duha Božjega gdje silazi kao golub i spušta se na nj."},{"v":17,"t":"I eto glasa s neba: “Ovo je Sin moj, Ljubljeni! U njemu mi sva milina!”"}]},"4":{"fa":[{"v":1,"t":"آنگاه عیسی به‌دست روح به بیابان برده شدتا ابلیس او را تجربه نماید."},{"v":2,"t":"و چون چهل شبانه‌روز روزه داشت، آخر گرسنه گردید."},{"v":3,"t":"پس تجربه کننده نزد او آمده، گفت: «اگر پسر خداهستی، بگو تا این سنگها نان شود.»"},{"v":4,"t":"در جواب گفت: «مکتوب است انسان نه محض نان زیست می‌کند، بلکه به هر کلمه‌ای که از دهان خدا صادرگردد.»"},{"v":5,"t":"آنگاه ابلیس او را به شهر مقدس برد و برکنگره هیکل برپا داشته،"},{"v":6,"t":"به وی گفت: «اگر پسرخدا هستی، خود را به زیر انداز، زیرا مکتوب است که فرشتگان خود را درباره تو فرمان دهد تاتو را به‌دستهای خود برگیرند، مبادا پایت به سنگی خورد.»"},{"v":7,"t":"عیسی وی را گفت: «و نیزمکتوب است خداوند خدای خود را تجربه مکن.»"},{"v":8,"t":"پس ابلیس او را به کوهی بسیار بلند برد وهمه ممالک جهان و جلال آنها را بدو نشان داده،"},{"v":9,"t":"به وی گفت: «اگر افتاده مرا سجده کنی، همانا این همه را به تو بخشم.»"},{"v":10,"t":"آنگاه عیسی وی راگفت: «دور شو‌ای شیطان، زیرا مکتوب است که خداوند خدای خود را سجده کن و او را فقطعبادت نما.»"},{"v":11,"t":"در ساعت ابلیس او را رها کرد واینک فرشتگان آمده، او را پرستاری می‌نمودند."},{"v":12,"t":"و چون عیسی شنید که یحیی گرفتار شده است، به جلیل روانه شد،"},{"v":13,"t":"و ناصره را ترک کرده، آمد و به کفرناحوم، به کناره دریا در حدودزبولون و نفتالیم ساکن شد."},{"v":14,"t":"تا تمام گردد آنچه به زبان اشعیای نبی گفته شده بود"},{"v":15,"t":"که «زمین زبولون و زمین نفتالیم، راه دریا آن طرف اردن، جلیل امت‌ها؛"},{"v":16,"t":"قومی که در ظلمت ساکن بودند، نوری عظیم دیدند و برنشینندگان دیار موت وسایه آن نوری تابید.»"},{"v":17,"t":"از آن هنگام عیسی به موعظه شروع کرد و گفت: «توبه کنید زیراملکوت آسمان نزدیک است.»"},{"v":18,"t":"و چون عیسی به کناره دریای جلیل می‌خرامید، دو برادر یعنی شمعون مسمی به پطرس و برادرش اندریاس را دید که دامی دردریا می‌اندازند، زیرا صیاد بودند."},{"v":19,"t":"بدیشان گفت: «از عقب من آیید تا شما را صیاد مردم گردانم.»"},{"v":20,"t":"در ساعت دامها را گذارده، از عقب او روانه شدند."},{"v":21,"t":"و چون از آنجا گذشت دو برادردیگر یعنی یعقوب، پسر زبدی و برادرش یوحنارا دید که در کشتی با پدر خویش زبدی، دامهای خود را اصلاح می‌کنند؛ ایشان را نیز دعوت نمود."},{"v":22,"t":"در حال، کشتی و پدر خود را ترک کرده، از عقب او روانه شدند."},{"v":23,"t":"و عیسی در تمام جلیل می‌گشت و درکنایس ایشان تعلیم داده، به بشارت ملکوت موعظه همی نمود و هر مرض و هر درد قوم راشفا می‌داد."},{"v":24,"t":"و اسم او در تمام سوریه شهرت یافت، و جمیع مریضانی که به انواع امراض ودردها مبتلا بودند و دیوانگان و مصروعان ومفلوجان را نزد او آوردند، و ایشان را شفا بخشید."},{"v":25,"t":"و گروهی بسیار از جلیل و دیکاپولس واورشلیم و یهودیه و آن طرف اردن در عقب اوروانه شدند."}],"en":[{"v":1,"t":"Then Jesus was led up by the Spirit into the wilderness to be tempted by the devil."},{"v":2,"t":"When he had fasted forty days and forty nights, he was hungry afterward."},{"v":3,"t":"The tempter came and said to him, “If you are the Son of God, command that these stones become bread.”"},{"v":4,"t":"But he answered, “It is written, ‘Man shall not live by bread alone, but by every word that proceeds out of God’s mouth.’”"},{"v":5,"t":"Then the devil took him into the holy city. He set him on the pinnacle of the temple,"},{"v":6,"t":"and said to him, “If you are the Son of God, throw yourself down, for it is written, ‘He will command his angels concerning you,’ and, ‘On their hands they will bear you up, so that you don’t dash your foot against a stone.’”"},{"v":7,"t":"Jesus said to him, “Again, it is written, ‘You shall not test the Lord, your God.’”"},{"v":8,"t":"Again, the devil took him to an exceedingly high mountain, and showed him all the kingdoms of the world and their glory."},{"v":9,"t":"He said to him, “I will give you all of these things, if you will fall down and worship me.”"},{"v":10,"t":"Then Jesus said to him, “Get behind me, Satan! For it is written, ‘You shall worship the Lord your God, and you shall serve him only.’”"},{"v":11,"t":"Then the devil left him, and behold, angels came and served him."},{"v":12,"t":"Now when Jesus heard that John was delivered up, he withdrew into Galilee."},{"v":13,"t":"Leaving Nazareth, he came and lived in Capernaum, which is by the sea, in the region of Zebulun and Naphtali,"},{"v":14,"t":"that it might be fulfilled which was spoken through Isaiah the prophet, saying,"},{"v":15,"t":"“The land of Zebulun and the land of Naphtali, toward the sea, beyond the Jordan, Galilee of the Gentiles,"},{"v":16,"t":"the people who sat in darkness saw a great light; to those who sat in the region and shadow of death, to them light has dawned.”"},{"v":17,"t":"From that time, Jesus began to preach, and to say, “Repent! For the Kingdom of Heaven is at hand.”"},{"v":18,"t":"Walking by the sea of Galilee, he saw two brothers: Simon, who is called Peter, and Andrew, his brother, casting a net into the sea; for they were fishermen."},{"v":19,"t":"He said to them, “Come after me, and I will make you fishers for men.”"},{"v":20,"t":"They immediately left their nets and followed him."},{"v":21,"t":"Going on from there, he saw two other brothers, James the son of Zebedee, and John his brother, in the boat with Zebedee their father, mending their nets. He called them."},{"v":22,"t":"They immediately left the boat and their father, and followed him."},{"v":23,"t":"Jesus went about in all Galilee, teaching in their synagogues, preaching the Good News of the Kingdom, and healing every disease and every sickness among the people."},{"v":24,"t":"The report about him went out into all Syria. They brought to him all who were sick, afflicted with various diseases and torments, possessed with demons, epileptics, and paralytics; and he healed them."},{"v":25,"t":"Great multitudes from Galilee, Decapolis, Jerusalem, Judea, and from beyond the Jordan followed him."}],"hr":[{"v":1,"t":"Duh tada odvede Isusa u pustinju da ga đavao iskuša."},{"v":2,"t":"I propostivši četrdeset dana i četrdeset noći, napokon ogladnje."},{"v":3,"t":"Tada mu pristupi napasnik i reče: “Ako si Sin Božji, reci da ovo kamenje postane kruhom.”"},{"v":4,"t":"A on odgovori: “Pisano je: Ne živi čovjek samo o kruhu, nego o svakoj riječi što izlazi iz Božjih usta.”"},{"v":5,"t":"Ðavao ga tada povede u Sveti grad, postavi ga na vrh Hrama"},{"v":6,"t":"i reče mu: “Ako si Sin Božji, baci se dolje! Ta pisano je: Anđelima će svojim zapovjediti za tebe i na rukama će te nositi da se gdje nogom ne spotakneš o kamen.”"},{"v":7,"t":"Isus mu kaza: “Pisano je također: Ne iskušavaj Gospodina, Boga svojega!”"},{"v":8,"t":"Ðavao ga onda povede na goru vrlo visoku i pokaza mu sva kraljevstva svijeta i slavu njihovu"},{"v":9,"t":"pa mu reče: “Sve ću ti to dati ako mi se ničice pokloniš.”"},{"v":10,"t":"Tada mu reče Isus: “Odlazi, Sotono! Ta pisano je: Gospodinu, Bogu svom se klanjaj i njemu jedinom služi!”"},{"v":11,"t":"Tada ga pusti đavao. I gle, anđeli pristupili i služili mu."},{"v":12,"t":"A čuvši da je Ivan predan, povuče se u Galileju."},{"v":13,"t":"Ostavi Nazaret te ode i nastani se u Kafarnaumu, uz more, na području Zebulunovu i Naftalijevu"},{"v":14,"t":"da se ispuni što je rečeno po proroku Izaiji:"},{"v":15,"t":"Zemlja Zebulunova i zemlja Naftalijeva, Put uz more, s one strane Jordana, Galileja poganska -"},{"v":16,"t":"narod što je sjedio u tmini svjetlost vidje veliku; onima što mrkli kraj smrti obitavahu svjetlost jarka osvanu."},{"v":17,"t":"Otada je Isus počeo propovijedati: “Obratite se jer približilo se kraljevstvo nebesko!”"},{"v":18,"t":"Prolazeći uz Galilejsko more, ugleda dva brata, Šimuna zvanog Petar i brata mu Andriju, gdje bacaju mrežu u more; bijahu ribari."},{"v":19,"t":"I kaže im: “Hajdete za mnom, učinit ću vas ribarima ljudi!”"},{"v":20,"t":"Oni brzo ostave mreže i pođu za njim."},{"v":21,"t":"Pošavši odande, ugleda druga dva brata, Jakova Zebedejeva i brata mu Ivana: u lađi su sa Zebedejem, ocem svojim, krpali mreže. Pozva i njih."},{"v":22,"t":"Oni brzo ostave lađu i oca te pođu za njim."},{"v":23,"t":"I obilazio je Isus svom Galilejom naučavajući po njihovim sinagogama, propovijedajući Evanđelje o Kraljevstvu i liječeći svaku bolest i svaku nemoć u narodu."},{"v":24,"t":"I glas se o njemu pronese svom Sirijom. I donosili su mu sve koji bolovahu od najrazličitijih bolesti i patnja - opsjednute, mjesečare, uzete - i on ih ozdravljaše."},{"v":25,"t":"Za njim je pohrlio silan svijet iz Galileje, Dekapola, Jeruzalema, Judeje i Transjordanije."}]},"5":{"fa":[{"v":1,"t":"خوشابحالها و گروهی بسیار دیده، بر فراز کوه آمد و وقتی که او بنشست شاگردانش نزد اوحاضر شدند."},{"v":2,"t":"آنگاه دهان خود را گشوده، ایشان را تعلیم داد و گفت:"},{"v":3,"t":"«خوشابحال مسکینان در روح، زیرا ملکوت آسمان از آن ایشان است."},{"v":4,"t":"خوشابحال ماتمیان، زیرا ایشان تسلی خواهند یافت."},{"v":5,"t":"خوشابحال حلیمان، زیرا ایشان وارث زمین خواهند شد."},{"v":6,"t":"خوشابحال گرسنگان و تشنگان عدالت، زیراایشان سیر خواهندشد."},{"v":7,"t":"خوشابحال رحم کنندگان، زیرا بر ایشان رحم کرده خواهدشد."},{"v":8,"t":"خوشابحال پاک دلان، زیرا ایشان خدا راخواهند دید."},{"v":9,"t":"خوشابحال صلح کنندگان، زیراایشان پسران خدا خوانده خواهند شد."},{"v":10,"t":"خوشابحال زحمت کشان برای عدالت، زیراملکوت آسمان از آن ایشان است."},{"v":11,"t":"خوشحال باشید چون شما را فحش گویند و جفا رسانند، وبخاطر من هر سخن بدی بر شما کاذبانه گویند."},{"v":12,"t":"خوش باشید و شادی عظیم نمایید، زیرا اجر شما در آسمان عظیم است زیرا که به همینطور بر انبیای قبل از شما جفامی رسانیدند."},{"v":13,"t":"«شما نمک جهانید! لیکن اگر نمک فاسدگردد، به کدام چیز باز نمکین شود؟ دیگر مصرفی ندارد جز آنکه بیرون افکنده، پایمال مردم شود."},{"v":14,"t":"شما نور عالمید. شهری که بر کوهی بنا شود، نتوان پنهان کرد."},{"v":15,"t":"و چراغ را نمی افروزند تا آن را زیر پیمانه نهند، بلکه تا بر چراغدان گذارند؛ آنگاه به همه کسانی که در خانه باشند، روشنایی می‌بخشد."},{"v":16,"t":"همچنین بگذارید نور شما بر مردم بتابد تا اعمال نیکوی شما را دیده، پدر شما را که در آسمان است تمجید نمایند."},{"v":17,"t":"«گمان مبرید که آمده‌ام تا تورات یا صحف انبیا را باطل سازم. نیامده‌ام تا باطل نمایم بلکه تاتمام کنم."},{"v":18,"t":"زیرا هر آینه به شما می‌گویم، تاآسمان و زمین زایل نشود، همزه یا نقطه‌ای ازتورات هرگز زایل نخواهد شد تا همه واقع شود."},{"v":19,"t":"پس هر‌که یکی از این احکام کوچکترین رابشکند و به مردم چنین تعلیم دهد، در ملکوت آسمان کمترین شمرده شود. اما هر‌که بعمل آورد و تعلیم نماید، او در ملکوت آسمان بزرگ خوانده خواهد شد."},{"v":20,"t":"زیرا به شما می‌گویم، تاعدالت شما بر عدالت کاتبان و فریسیان افزون نشود، به ملکوت آسمان هرگز داخل نخواهیدشد."},{"v":21,"t":"«شنیده‌اید که به اولین گفته شده است “قتل مکن و هر‌که قتل کند سزاوار حکم شود.”"},{"v":22,"t":"لیکن من به شما می‌گویم، هر‌که به برادر خود بی‌سبب خشم گیرد، مستوجب حکم باشد و هر‌که برادرخود را راقا گوید، مستوجب قصاص باشد و هرکه احمق گوید، مستحق آتش جهنم بود."},{"v":23,"t":"پس هرگاه هدیه خود را به قربانگاه ببری و آنجا به‌خاطرت آید که برادرت بر تو حقی دارد،"},{"v":24,"t":"هدیه خود را پیش قربانگاه واگذار و رفته، اول با برادرخویش صلح نما و بعد آمده، هدیه خود رابگذران."},{"v":25,"t":"با مدعی خود مادامی که با وی در راه هستی صلح کن، مبادا مدعی، تو را به قاضی سپارد و قاضی، تو را به داروغه تسلیم کند و در زندان افکنده شوی."},{"v":26,"t":"هرآینه به تو می‌گویم، که تا فلس آخر را ادا نکنی، هرگز از آنجا بیرون نخواهی آمد."},{"v":27,"t":"«شنیده‌اید که به اولین گفته شده است “زنامکن.”"},{"v":28,"t":"لیکن من به شما می‌گویم، هر کس به زنی نظر شهوت اندازد، همان دم در دل خود با او زناکرده است."},{"v":29,"t":"پس اگر چشم راستت تو رابلغزاند، قلعش کن و از خود دور انداز زیرا تو رابهتر آن است که عضوی از اعضایت تباه گردد، ازآنکه تمام بدنت در جهنم افکنده شود."},{"v":30,"t":"و اگردست راستت تو را بلغزاند، قطعش کن و از خوددور انداز، زیرا تو را مفیدتر آن است که عضوی ازاعضای تو نابود شود، از آنکه کل جسدت دردوزخ افکنده شود."},{"v":31,"t":"«و گفته شده است هر‌که از زن خودمفارقت جوید، طلاق نامه‌ای بدو بدهد."},{"v":32,"t":"لیکن من به شما می‌گویم، هر کس بغیر علت زنا، زن خود را از خود جدا کند باعث زنا کردن اومی باشد، و هر‌که زن مطلقه را نکاح کند، زنا کرده باشد."},{"v":33,"t":"«باز شنیده‌اید که به اولین گفته شده است که “قسم دروغ مخور، بلکه قسم های خود را به خداوند وفا کن.”"},{"v":34,"t":"لیکن من به شما می‌گویم، هرگز قسم مخورید، نه به آسمان زیرا که عرش خداست،"},{"v":35,"t":"و نه به زمین زیرا که پای انداز اواست، و نه به ارشلیم زیرا که شهر پادشاه عظیم است،"},{"v":36,"t":"و نه به‌سر خود قسم یاد کن، زیرا که مویی را سفید یا سیاه نمی توانی کرد."},{"v":37,"t":"بلکه سخن شما بلی بلی و نی نی باشد زیرا که زیاده براین از شریر است."},{"v":38,"t":"«شنیده‌اید که گفته شده است.”چشمی به چشمی و دندانی به دندانی “"},{"v":39,"t":"لیکن من به شمامی گویم، با شریر مقاومت مکنید بلکه هر‌که بررخساره راست تو طپانچه زند، دیگری را نیز به سوی او بگردان،"},{"v":40,"t":"و اگر کسی خواهد با تو دعواکند و قبای تو را بگیرد، عبای خود را نیز بدوواگذار،"},{"v":41,"t":"و هرگاه کسی تو را برای یک میل مجبور سازد، دو میل همراه او برو."},{"v":42,"t":"هر کس ازتو سوال کند، بدو ببخش و از کسی‌که قرض از توخواهد، روی خود را مگردان.»"},{"v":43,"t":"«شنیده‌اید که گفته شده است “همسایه خورا محبت نما و با دشمن خود عداوت کن.”"},{"v":44,"t":"امامن به شما می‌گویم که دشمنان خود را محبت نمایید و برای لعن کنندگان خود برکت بطلبید و به آنانی که از شما نفرت کنند، احسان کنید و به هرکه به شما فحش دهد و جفا رساند، دعای خیرکنید،"},{"v":45,"t":"تا پدر خود را که در آسمان است پسران شوید، زیرا که آفتاب خود را بر بدان و نیکان طالع می‌سازد و باران بر عادلان و ظالمان می‌باراند."},{"v":46,"t":"زیرا هرگاه آنانی را محبت نمایید که شما رامحبت می‌نمایند، چه اجر دارید؟ آیا باجگیران چنین نمی کنند؟"},{"v":47,"t":"و هرگاه برادران خود را فقطسلام گویید چه فضیلت دارید؟ آیا باجگیران چنین نمی کنند؟"},{"v":48,"t":"پس شما کامل باشید چنانکه پدر شما که در آسمان است کامل است."}],"en":[{"v":1,"t":"Seeing the multitudes, he went up onto the mountain. When he had sat down, his disciples came to him."},{"v":2,"t":"He opened his mouth and taught them, saying,"},{"v":3,"t":"“Blessed are the poor in spirit, for theirs is the Kingdom of Heaven."},{"v":4,"t":"Blessed are those who mourn, for they shall be comforted."},{"v":5,"t":"Blessed are the gentle, for they shall inherit the earth."},{"v":6,"t":"Blessed are those who hunger and thirst for righteousness, for they shall be filled."},{"v":7,"t":"Blessed are the merciful, for they shall obtain mercy."},{"v":8,"t":"Blessed are the pure in heart, for they shall see God."},{"v":9,"t":"Blessed are the peacemakers, for they shall be called children of God."},{"v":10,"t":"Blessed are those who have been persecuted for righteousness’ sake, for theirs is the Kingdom of Heaven."},{"v":11,"t":"“Blessed are you when people reproach you, persecute you, and say all kinds of evil against you falsely, for my sake."},{"v":12,"t":"Rejoice, and be exceedingly glad, for great is your reward in heaven. For that is how they persecuted the prophets who were before you."},{"v":13,"t":"“You are the salt of the earth, but if the salt has lost its flavor, with what will it be salted? It is then good for nothing, but to be cast out and trodden under the feet of men."},{"v":14,"t":"You are the light of the world. A city located on a hill can’t be hidden."},{"v":15,"t":"Neither do you light a lamp and put it under a measuring basket, but on a stand; and it shines to all who are in the house."},{"v":16,"t":"Even so, let your light shine before men, that they may see your good works and glorify your Father who is in heaven."},{"v":17,"t":"“Don’t think that I came to destroy the law or the prophets. I didn’t come to destroy, but to fulfill."},{"v":18,"t":"For most certainly, I tell you, until heaven and earth pass away, not even one smallest letter or one tiny pen stroke shall in any way pass away from the law, until all things are accomplished."},{"v":19,"t":"Therefore, whoever shall break one of these least commandments and teach others to do so, shall be called least in the Kingdom of Heaven; but whoever shall do and teach them shall be called great in the Kingdom of Heaven."},{"v":20,"t":"For I tell you that unless your righteousness exceeds that of the scribes and Pharisees, there is no way you will enter into the Kingdom of Heaven."},{"v":21,"t":"“You have heard that it was said to the ancient ones, ‘You shall not murder;’ and ‘Whoever murders will be in danger of the judgment.’"},{"v":22,"t":"But I tell you that everyone who is angry with his brother without a cause will be in danger of the judgment. Whoever says to his brother, ‘Raca!’ will be in danger of the council. Whoever says, ‘You fool!’ will be in danger of the fire of Gehenna."},{"v":23,"t":"“If therefore you are offering your gift at the altar, and there remember that your brother has anything against you,"},{"v":24,"t":"leave your gift there before the altar, and go your way. First be reconciled to your brother, and then come and offer your gift."},{"v":25,"t":"Agree with your adversary quickly while you are with him on the way; lest perhaps the prosecutor deliver you to the judge, and the judge deliver you to the officer, and you be cast into prison."},{"v":26,"t":"Most certainly I tell you, you shall by no means get out of there until you have paid the last penny."},{"v":27,"t":"“You have heard that it was said, ‘You shall not commit adultery;’"},{"v":28,"t":"but I tell you that everyone who gazes at a woman to lust after her has committed adultery with her already in his heart."},{"v":29,"t":"If your right eye causes you to stumble, pluck it out and throw it away from you. For it is more profitable for you that one of your members should perish than for your whole body to be cast into Gehenna."},{"v":30,"t":"If your right hand causes you to stumble, cut it off, and throw it away from you. For it is more profitable for you that one of your members should perish, than for your whole body to be cast into Gehenna."},{"v":31,"t":"“It was also said, ‘Whoever shall put away his wife, let him give her a writing of divorce,’"},{"v":32,"t":"but I tell you that whoever puts away his wife, except for the cause of sexual immorality, makes her an adulteress; and whoever marries her when she is put away commits adultery."},{"v":33,"t":"“Again you have heard that it was said to the ancient ones, ‘You shall not make false vows, but shall perform to the Lord your vows,’"},{"v":34,"t":"but I tell you, don’t swear at all: neither by heaven, for it is the throne of God;"},{"v":35,"t":"nor by the earth, for it is the footstool of his feet; nor by Jerusalem, for it is the city of the great King."},{"v":36,"t":"Neither shall you swear by your head, for you can’t make one hair white or black."},{"v":37,"t":"But let your ‘Yes’ be ‘Yes’ and your ‘No’ be ‘No.’ Whatever is more than these is of the evil one."},{"v":38,"t":"“You have heard that it was said, ‘An eye for an eye, and a tooth for a tooth.’"},{"v":39,"t":"But I tell you, don’t resist him who is evil; but whoever strikes you on your right cheek, turn to him the other also."},{"v":40,"t":"If anyone sues you to take away your coat, let him have your cloak also."},{"v":41,"t":"Whoever compels you to go one mile, go with him two."},{"v":42,"t":"Give to him who asks you, and don’t turn away him who desires to borrow from you."},{"v":43,"t":"“You have heard that it was said, ‘You shall love your neighbor and hate your enemy.’"},{"v":44,"t":"But I tell you, love your enemies, bless those who curse you, do good to those who hate you, and pray for those who mistreat you and persecute you,"},{"v":45,"t":"that you may be children of your Father who is in heaven. For he makes his sun to rise on the evil and the good, and sends rain on the just and the unjust."},{"v":46,"t":"For if you love those who love you, what reward do you have? Don’t even the tax collectors do the same?"},{"v":47,"t":"If you only greet your friends, what more do you do than others? Don’t even the tax collectors do the same?"},{"v":48,"t":"Therefore you shall be perfect, just as your Father in heaven is perfect."}],"hr":[{"v":1,"t":"Ugledavši mnoštvo, uziđe na goru. I kad sjede, pristupe mu učenici."},{"v":2,"t":"On progovori i stane ih naučavati:"},{"v":3,"t":"“Blago siromasima duhom: njihovo je kraljevstvo nebesko!"},{"v":4,"t":"Blago ožalošćenima: oni će se utješiti!"},{"v":5,"t":"Blago krotkima: oni će baštiniti zemlju!"},{"v":6,"t":"Blago gladnima i žednima pravednosti: oni će se nasititi!"},{"v":7,"t":"Blago milosrdnima: oni će zadobiti milosrđe!"},{"v":8,"t":"Blago čistima srcem: oni će Boga gledati!"},{"v":9,"t":"Blago mirotvorcima: oni će se sinovima Božjim zvati!"},{"v":10,"t":"Blago progonjenima zbog pravednosti: njihovo je kraljevstvo nebesko!”"},{"v":11,"t":"“Blago vama kad vas - zbog mene - pogrde i prognaju i sve zlo slažu protiv vas!"},{"v":12,"t":"Radujte se i kličite: velika je plaća vaša na nebesima! Ta progonili su tako proroke prije vas!”"},{"v":13,"t":"“Vi ste sol zemlje. Ali ako sol obljutavi, čime će se ona osoliti? Nije više ni za što, nego da se baci van i da ljudi po njoj gaze.”"},{"v":14,"t":"“Vi ste svjetlost svijeta. Ne može se sakriti grad što leži na gori."},{"v":15,"t":"Niti se užiže svjetiljka da se stavi pod posudu, nego na svijećnjak da svijetli svima u kući."},{"v":16,"t":"Tako neka svijetli vaša svjetlost pred ljudima da vide vaša dobra djela i slave Oca vašega koji je na nebesima.”"},{"v":17,"t":"“Ne mislite da sam došao ukinuti Zakon ili Proroke. Nisam došao ukinuti, nego ispuniti."},{"v":18,"t":"Zaista, kažem vam, dok ne prođe nebo i zemlja, ne, ni jedno slovce, ni jedan potezić iz Zakona neće proći, dok se sve ne zbude."},{"v":19,"t":"Tko dakle ukine jednu od tih, pa i najmanjih zapovijedi i tako nauči ljude, najmanji će biti u kraljevstvu nebeskom. A tko ih bude vršio i druge učio, taj će biti velik u kraljevstvu nebeskom.”"},{"v":20,"t":"“Uistinu kažem vam: ne bude li pravednost vaša veća od pravednosti pismoznanaca i farizeja, ne, nećete ući u kraljevstvo nebesko.”"},{"v":21,"t":"“Čuli ste da je rečeno starima: Ne ubij! Tko ubije, bit će podvrgnut sudu."},{"v":22,"t":"A ja vam kažem: Svaki koji se srdi na brata svoga, bit će podvrgnut sudu. A tko bratu rekne 'Glupane!', bit će podvrgnut Vijeću. A tko reče: 'Luđače!', bit će podvrgnut ognju paklenomu.”"},{"v":23,"t":"“Ako dakle prinosiš dar na žrtvenik pa se ondje sjetiš da tvoj brat ima nešto protiv tebe,"},{"v":24,"t":"ostavi dar ondje pred žrtvenikom, idi i najprije se izmiri s bratom, a onda dođi i prinesi dar.”"},{"v":25,"t":"“Nagodi se brzo s protivnikom dok si još s njim na putu, da te protivnik ne preda sucu, a sudac tamničaru, pa da te ne bace u tamnicu."},{"v":26,"t":"Zaita, kažem ti, nećeš izići odande dok ne isplatiš do posljednjeg novčića.”"},{"v":27,"t":"“Čuli ste da je rečeno: Ne čini preljuba!"},{"v":28,"t":"A ja vam kažem: Tko god s požudom pogleda ženu, već je s njome učinio preljub u srcu."},{"v":29,"t":"Ako te desno oko sablažnjava, iskopaj ga i baci od sebe. Ta bolje je da ti propadne jedan od udova, nego da ti cijelo tijelo bude bačeno u pakao."},{"v":30,"t":"Ako te desnica tvoja sablažnjava, odsijeci je i baci od sebe. Ta bolje je da ti propadne jedan od udova, nego da ti cijelo tijelo ode u pakao.”"},{"v":31,"t":"“Rečeno je također: Tko otpusti svoju ženu, neka joj dade otpusnicu."},{"v":32,"t":"A ja vam kažem: Tko god otpusti svoju ženu - osim zbog bludništva - navodi je na preljub i tko se god otpuštenom oženi, čini preljub.”"},{"v":33,"t":"“Čuli ste još da je rečeno starima: Ne zaklinji se krivo, nego izvrši Gospodinu svoje zakletve."},{"v":34,"t":"A ja vam kažem: Ne kunite se nikako! Ni nebom jer je prijestolje Božje."},{"v":35,"t":"Ni zemljom jer je podnožje njegovim nogama. Ni Jeruzalemom jer grad je Kralja velikoga!"},{"v":36,"t":"Ni svojom se glavom ne zaklinji jer ni jedne vlasi ne možeš učiniti bijelom ili crnom."},{"v":37,"t":"Vaša riječ neka bude: 'Da, da, - ne, ne!' Što je više od toga, od Zloga je.”"},{"v":38,"t":"“Čuli ste da je rečeno: Oko za oko, zub za zub!"},{"v":39,"t":"A ja vam kažem: Ne opirite se Zlomu! Naprotiv, pljusne li te tko po desnom obrazu, okreni mu i drugi."},{"v":40,"t":"Onomu tko bi se htio s tobom parničiti da bi se domogao tvoje donje haljine prepusti i gornju."},{"v":41,"t":"Ako te tko prisili jednu milju, pođi s njim dvije."},{"v":42,"t":"Tko od tebe što zaište, podaj mu! I ne okreni se od onoga koji hoće da mu pozajmiš.”"},{"v":43,"t":"“Čuli ste da je rečeno: Ljubi svoga bližnjega, a mrzi neprijatelja."},{"v":44,"t":"A ja vam kažem: Ljubite neprijatelje, molite za one koji vas progone"},{"v":45,"t":"da budete sinovi svoga oca koji je na nebesima, jer on daje da sunce njegovo izlazi nad zlima i dobrima i da kiša pada pravednicima i nepravednicima."},{"v":46,"t":"Jer ako ljubite one koji vas ljube, kakva li vam plaća? Zar to isto ne čine i carinici?"},{"v":47,"t":"I ako pozdravljate samo braću, što osobito činite? Zar to isto ne čine i pogani?”"},{"v":48,"t":"“Budite dakle savršeni kao što je savršen Otac vaš nebeski!”"}]},"6":{"fa":[{"v":1,"t":"«زنهار عدالت خود را پیش مردم به‌جامیاورید تا شما را ببینند و الا نزد پدر خودکه در آسمان است، اجری ندارید."},{"v":2,"t":"پس چون صدقه دهی، پیش خود کرنا منواز چنانکه ریاکاران در کنایس و بازارها می‌کنند، تا نزد مردم اکرام یابند. هرآینه به شما می‌گویم اجر خود رایافته‌اند."},{"v":3,"t":"بلکه تو چون صدقه دهی، دست چپ تو از آنچه دست راستت می‌کند مطلع نشود،"},{"v":4,"t":"تاصدقه تو در نهان باشد و پدر نهان بین تو، تو راآشکارا اجر خواهد داد."},{"v":5,"t":"«و چون عبادت کنی، مانند ریاکاران مباش زیرا خوش دارند که در کنایس و گوشه های کوچه‌ها ایستاده، نماز گذارند تا مردم ایشان راببینند. هرآینه به شما می‌گویم اجر خود راتحصیل نموده‌اند."},{"v":6,"t":"لیکن تو چون عبادت کنی، به حجره خود داخل شو و در را بسته، پدر خود راکه در نهان است عبادت نما؛ و پدر نهان بین تو، تو را آشکارا جزا خواهد داد."},{"v":7,"t":"و چون عبادت کنید، مانند امت‌ها تکرار باطل مکنید زیرا ایشان گمان می‌برند که به‌سبب زیاد گفتن مستجاب می‌شوند."},{"v":8,"t":"پس مثل ایشان مباشید زیرا که پدر شماحاجات شما را می‌داند پیش از آنکه از او سوال کنید."},{"v":9,"t":"«پس شما به اینطور دعا کنید: “ای پدر ما که در آسمانی، نام تو مقدس باد."},{"v":10,"t":"ملکوت تو بیاید. اراده تو چنانکه در آسمان است، بر زمین نیز کرده شود."},{"v":11,"t":"نان کفاف ما را امروز به ما بده."},{"v":12,"t":"و قرض های ما را ببخش چنانکه ما نیزقرضداران خود را می‌بخشیم."},{"v":13,"t":"و ما را در آزمایش میاور، بلکه از شریر ما رارهایی ده."},{"v":14,"t":"«زیرا هرگاه تقصیرات مردم را بدیشان بیامرزید، پدر آسمانی شما، شما را نیز خواهدآمرزید."},{"v":15,"t":"اما اگر تقصیرهای مردم را نیامرزید، پدر شما هم تقصیرهای شما را نخواهد آمرزید."},{"v":16,"t":"«اما چون روزه‌دارید، مانند ریاکاران ترشرو مباشید زیرا که صورت خویش را تغییرمی دهند تا در نظر مردم روزه‌دار نمایند. هرآینه به شما می‌گویم اجر خود را یافته‌اند."},{"v":17,"t":"لیکن توچون روزه‌داری، سر خود را تدهین کن و روی خود را بشوی"},{"v":18,"t":"تا در نظر مردم روزه‌دار ننمایی، بلکه در حضور پدرت که در نهان است؛ و پدر نهان بین تو، تو را آشکارا جزا خواهد داد."},{"v":19,"t":"«گنجها برای خود بر زمین نیندوزید، جایی که بید و زنگ زیان می‌رساند و جایی که دزدان نقب می‌زنند و دزدی می‌نمایند."},{"v":20,"t":"بلکه گنجهابجهت خود در آسمان بیندوزید، جایی که بید وزنگ زیان نمی رساند و جایی که دزدان نقب نمی زنند و دزدی نمی کنند."},{"v":21,"t":"زیرا هرجا گنج تواست دل تو نیز در آنجا خواهد بود."},{"v":22,"t":"«چراغ بدن چشم است؛ پس هرگاه چشمت بسیط باشد تمام بدنت روشن بود؛"},{"v":23,"t":"امااگر چشم تو فاسد است، تمام جسدت تاریک می‌باشد. پس اگر نوری که در تو است ظلمت باشد، چه ظلمت عظیمی است!"},{"v":24,"t":"«هیچ‌کس دو آقا را خدمت نمی تواند کرد، زیرا یا از یکی نفرت دارد و با دیگری محبت، و یابه یکی می‌چسبد و دیگر را حقیر می‌شمارد. محال است که خدا و ممونا را خدمت کنید."},{"v":25,"t":"«بنابراین به شما می‌گویم، از بهر جان خوداندیشه مکنید که چه خورید یا چه آشامید و نه برای بدن خود که چه بپوشید. آیا جان، از خوراک و بدن از پوشاک بهتر نیست؟"},{"v":26,"t":"مرغان هوا را نظرکنید که نه می‌کارند و نه می‌دروند و نه در انبارهاذخیره می‌کنند و پدر آسمانی شما آنها رامی پروراند. آیا شما از آنها بمراتب بهتر نیستید؟"},{"v":27,"t":"و کیست از شما که به تفکر بتواند ذراعی برقامت خود افزاید؟"},{"v":28,"t":"و برای لباس چرا می اندیشید؟ در سوسنهای چمن تامل کنید، چگونه نمو می‌کنند! نه محنت می‌کشند و نه می‌ریسند!"},{"v":29,"t":"لیکن به شما می‌گویم سلیمان هم باهمه جلال خود چون یکی از آنها آراسته نشد."},{"v":30,"t":"پس اگر خدا علف صحرا را که امروز هست وفردا در تنور افکنده می‌شود چنین بپوشاند، ای کم‌ایمانان آیا نه شما را از طریق اولی؟"},{"v":31,"t":"پس اندیشه مکنید و مگویید چه بخوریم یا چه بنوشیم یا چه بپوشیم."},{"v":32,"t":"زیرا که در طلب جمیع این چیزها امت‌ها می‌باشند. اما پدر آسمانی شمامی داند که بدین همه‌چیز احتیاج دارید."},{"v":33,"t":"لیکن اول ملکوت خدا و عدالت او را بطلبید که این همه برای شما مزید خواهد شد."},{"v":34,"t":"پس در اندیشه فردا مباشید زیرا فردا اندیشه خود را خواهد کرد. بدی امروز برای امروز کافی است."}],"en":[{"v":1,"t":"“Be careful that you don’t do your charitable giving before men, to be seen by them, or else you have no reward from your Father who is in heaven."},{"v":2,"t":"Therefore, when you do merciful deeds, don’t sound a trumpet before yourself, as the hypocrites do in the synagogues and in the streets, that they may get glory from men. Most certainly I tell you, they have received their reward."},{"v":3,"t":"But when you do merciful deeds, don’t let your left hand know what your right hand does,"},{"v":4,"t":"so that your merciful deeds may be in secret, then your Father who sees in secret will reward you openly."},{"v":5,"t":"“When you pray, you shall not be as the hypocrites, for they love to stand and pray in the synagogues and in the corners of the streets, that they may be seen by men. Most certainly, I tell you, they have received their reward."},{"v":6,"t":"But you, when you pray, enter into your inner room, and having shut your door, pray to your Father who is in secret; and your Father who sees in secret will reward you openly."},{"v":7,"t":"In praying, don’t use vain repetitions as the Gentiles do; for they think that they will be heard for their much speaking."},{"v":8,"t":"Therefore don’t be like them, for your Father knows what things you need before you ask him."},{"v":9,"t":"Pray like this: “‘Our Father in heaven, may your name be kept holy."},{"v":10,"t":"Let your Kingdom come. Let your will be done on earth as it is in heaven."},{"v":11,"t":"Give us today our daily bread."},{"v":12,"t":"Forgive us our debts, as we also forgive our debtors."},{"v":13,"t":"Bring us not into temptation, but deliver us from the evil one. For yours is the Kingdom, the power, and the glory forever. Amen.’"},{"v":14,"t":"“For if you forgive men their trespasses, your heavenly Father will also forgive you."},{"v":15,"t":"But if you don’t forgive men their trespasses, neither will your Father forgive your trespasses."},{"v":16,"t":"“Moreover when you fast, don’t be like the hypocrites, with sad faces. For they disfigure their faces that they may be seen by men to be fasting. Most certainly I tell you, they have received their reward."},{"v":17,"t":"But you, when you fast, anoint your head and wash your face,"},{"v":18,"t":"so that you are not seen by men to be fasting, but by your Father who is in secret; and your Father, who sees in secret, will reward you."},{"v":19,"t":"“Don’t lay up treasures for yourselves on the earth, where moth and rust consume, and where thieves break through and steal;"},{"v":20,"t":"but lay up for yourselves treasures in heaven, where neither moth nor rust consume, and where thieves don’t break through and steal;"},{"v":21,"t":"for where your treasure is, there your heart will be also."},{"v":22,"t":"“The lamp of the body is the eye. If therefore your eye is sound, your whole body will be full of light."},{"v":23,"t":"But if your eye is evil, your whole body will be full of darkness. If therefore the light that is in you is darkness, how great is the darkness!"},{"v":24,"t":"“No one can serve two masters, for either he will hate the one and love the other, or else he will be devoted to one and despise the other. You can’t serve both God and Mammon."},{"v":25,"t":"Therefore I tell you, don’t be anxious for your life: what you will eat, or what you will drink; nor yet for your body, what you will wear. Isn’t life more than food, and the body more than clothing?"},{"v":26,"t":"See the birds of the sky, that they don’t sow, neither do they reap, nor gather into barns. Your heavenly Father feeds them. Aren’t you of much more value than they?"},{"v":27,"t":"“Which of you by being anxious, can add one moment to his lifespan?"},{"v":28,"t":"Why are you anxious about clothing? Consider the lilies of the field, how they grow. They don’t toil, neither do they spin,"},{"v":29,"t":"yet I tell you that even Solomon in all his glory was not dressed like one of these."},{"v":30,"t":"But if God so clothes the grass of the field, which today exists and tomorrow is thrown into the oven, won’t he much more clothe you, you of little faith?"},{"v":31,"t":"“Therefore don’t be anxious, saying, ‘What will we eat?’, ‘What will we drink?’ or, ‘With what will we be clothed?’"},{"v":32,"t":"For the Gentiles seek after all these things; for your heavenly Father knows that you need all these things."},{"v":33,"t":"But seek first God’s Kingdom and his righteousness; and all these things will be given to you as well."},{"v":34,"t":"Therefore don’t be anxious for tomorrow, for tomorrow will be anxious for itself. Each day’s own evil is sufficient."}],"hr":[{"v":1,"t":"“Pazite da svoje pravednosti ne činite pred ljudima da vas oni vide. Inače, nema vam plaće u vašeg Oca koji je na nebesima."},{"v":2,"t":"Kada dakle dijeliš milostinju, ne trubi pred sobom, kako to u sinagogama i na ulicama čine licemjeri da bi ih ljudi hvalili. Zaista, kažem vam, primili su svoju plaću."},{"v":3,"t":"Ti naprotiv, kada daješ milostinju - neka ti ne zna ljevica što čini desnica,"},{"v":4,"t":"da tvoja milostinja bude u skrovitosti. I Otac tvoj, koji vidi u skrovitosti, uzvratit će ti!”"},{"v":5,"t":"“Tako i kad molite, ne budite kao licemjeri. Vole moliti stojeći u sinagogama i na raskršćima ulica da se pokažu ljudima. Zaista, kažem vam, primili su svoju plaću."},{"v":6,"t":"Ti naprotiv, kad moliš, uđi u svoju sobu, zatvori vrata i pomoli se svomu Ocu, koji je u skrovitosti. I Otac tvoj, koji vidi u skrovitosti, uzvratit će ti.”"},{"v":7,"t":"“Kad molite, ne blebećite kao pogani. Misle da će s mnoštva riječi biti uslišani."},{"v":8,"t":"Ne nalikujte na njih. Ta zna vaš Otac što vam treba i prije negoli ga zaištete."},{"v":9,"t":"Vi, dakle, ovako molite: 'Oče naš, koji jesi na nebesima! Sveti se ime tvoje!"},{"v":10,"t":"Dođi kraljevstvo tvoje! Budi volja tvoja kako na nebu tako i na zemlji!"},{"v":11,"t":"Kruh naš svagdanji daj nam danas!"},{"v":12,"t":"I opusti nam duge naše kako i mi otpustismo dužnicima svojim!"},{"v":13,"t":"I ne uvedi nas u napast, nego izbavi nas od Zloga!'”"},{"v":14,"t":"“Doista, ako vi otpustite ljudima njihove prijestupke, otpustit će i vama Otac vaš nebeski."},{"v":15,"t":"Ako li vi ne otpustite ljudima, ni Otac vaš neće otpustiti vaših prijestupaka.”"},{"v":16,"t":"“I kad postite, ne budite smrknuti kao licemjeri. Izobličuju lica da pokažu ljudima kako poste. Zaista, kažem vam, primili su svoju plaću."},{"v":17,"t":"Ti naprotiv, kad postiš, pomaži glavu i umij lice"},{"v":18,"t":"da ne zapaze ljudi kako postiš, nego Otac tvoj, koji je u skrovitosti. I Otac tvoj, koji vidi u skrovitosti, uzvratit će ti.”"},{"v":19,"t":"“Ne zgrćite sebi blago na zemlji, gdje ga moljac i rđa nagrizaju i gdje ga kradljivci potkapaju i kradu."},{"v":20,"t":"Zgrćite sebi blago na nebu, gdje ga ni moljac ni rđa ne nagrizaju i gdje kradljivci ne potkapaju niti kradu."},{"v":21,"t":"Doista, gdje ti je blago, ondje će ti biti i srce.”"},{"v":22,"t":"“Oko je tijelu svjetiljka. Ako ti je dakle oko bistro, sve će tijelo tvoje biti svijetlo."},{"v":23,"t":"Ako ti je pak oko nevaljalo, sve će tijelo tvoje biti tamno. Ako je dakle svjetlost koja je u tebi - tamna, kolika će istom tama biti?”"},{"v":24,"t":"“Nitko ne može služiti dvojici gospodara. Ili će jednoga mrziti, a drugoga ljubiti; ili će uz jednoga prianjati, a drugoga prezirati. Ne možete služiti Bogu i bogatstvu.”"},{"v":25,"t":"“Zato vam kažem: Ne budite zabrinuti za život svoj: što ćete jesti, što ćete piti; ni za tijelo svoje: u što ćete se obući. Zar život nije vredniji od jela i tijelo od odijela?”"},{"v":26,"t":"“Pogledajte ptice nebeske! Ne siju, ne žanju niti sabiru u žitnice, pa ipak ih hrani vaš nebeski Otac. Zar niste vi vredniji od njih?"},{"v":27,"t":"A tko od vas zabrinutošću može svome stasu dodati jedan lakat?"},{"v":28,"t":"I za odijelo što ste zabrinuti? Promotrite poljske ljiljane, kako rastu! Ne muče se niti predu."},{"v":29,"t":"A kažem vam: ni Salomon se u svoj svojoj slavi ne zaodjenu kao jedan od njih."},{"v":30,"t":"Pa ako travu poljsku, koja danas jest a sutra se u peć baca, Bog tako odijeva, neće li još više vas, malovjerni?”"},{"v":31,"t":"“Nemojte dakle zabrinuto govoriti: 'Što ćemo jesti?' ili: 'Što ćemo piti?' ili: 'U što ćemo se obući?'"},{"v":32,"t":"Ta sve to pogani ištu. Zna Otac vaš nebeski da vam je sve to potrebno."},{"v":33,"t":"Tražite stoga najprije Kraljevstvo i pravednost njegovu, a sve će vam se ostalo dodati."},{"v":34,"t":"Ne budite dakle zabrinuti za sutra. Sutra će se samo brinuti za se. Dosta je svakom danu zla njegova.”"}]},"7":{"fa":[{"v":1,"t":"«حکم مکنید تا بر شما حکم نشود."},{"v":2,"t":"زیرابدان طریقی که حکم کنید بر شما نیز حکم خواهد شد و بدان پیمانه‌ای که پیمایید برای شماخواهند پیمود."},{"v":3,"t":"و چون است که خس را درچشم برادر خود می‌بینی و چوبی را که چشم خود داری نمی یابی؟"},{"v":4,"t":"یا چگونه به برادر خودمی گویی “اجازت ده تا خس را از چشمت بیرون کنم “ و اینک چوب در چشم تو است؟"},{"v":5,"t":"‌ای ریاکار، اول چوب را از چشم خود بیرون کن، آنگاه نیک خواهی دید تا خس را از چشم برادرت بیرون کنی!"},{"v":6,"t":"«آنچه مقدس است، به سگان مدهید و نه مرواریدهای خود را پیش گرازان اندازید، مباداآنها را پایمال کنند و برگشته، شما را بدرند."},{"v":7,"t":"«سوال کنید که به شما داده خواهد شد؛ بطلبید که خواهید یافت؛ بکوبید که برای شما بازکرده خواهد شد."},{"v":8,"t":"زیرا هر‌که سوال کند، یابد وکسی‌که بطلبد دریافت کند و هر‌که بکوبد برای اوگشاده خواهد شد."},{"v":9,"t":"و کدام آدمی است از شما که پسرش نانی از او خواهد و سنگی بدو دهد؟"},{"v":10,"t":"یااگر ماهی خواهد ماری بدو بخشد؟"},{"v":11,"t":"پس هرگاه شما که شریر هستید، دادن بخشش های نیکو را به اولاد خود می‌دانید، چقدر زیاده پدر شما که درآسمان است چیزهای نیکو را به آنانی که از اوسوال می‌کنند خواهد بخشید!"},{"v":12,"t":"لهذا آنچه خواهید که مردم به شما کنند، شما نیز بدیشان همچنان کنید، زیرا این است تورات و صحف انبیا."},{"v":13,"t":"«از در تنگ داخل شوید. زیرا فراخ است آن در و وسیع است آن طریقی که مودی به هلاکت است و آنانی که بدان داخل می‌شوندبسیارند."},{"v":14,"t":"زیرا تنگ است آن در و دشوار است آن طریقی که مودی به حیات‌است و یابندگان آن کمند."},{"v":15,"t":"«اما از انبیای کذبه احتراز کنید، که به لباس میشها نزد شما می‌آیند ولی در باطن، گرگان درنده می‌باشند."},{"v":16,"t":"ایشان را از میوه های ایشان خواهید شناخت. آیا انگور را از خار و انجیر را ازخس می‌چینند؟"},{"v":17,"t":"همچنین هر درخت نیکو، میوه نیکو می‌آورد و درخت بد، میوه بد می‌آورد."},{"v":18,"t":"نمی تواند درخت خوب میوه بد آورد، و نه درخت بد میوه نیکو آورد."},{"v":19,"t":"هر درختی که میوه نیکو نیاورد، بریده و در آتش افکنده شود."},{"v":20,"t":"لهذا از میوه های ایشان، ایشان را خواهیدشناخت."},{"v":21,"t":"«نه هر‌که مرا “خداوند، خداوند” گویدداخل ملکوت آسمان گردد، بلکه آنکه اراده پدرمرا که در آسمان است به‌جا آورد."},{"v":22,"t":"بسا در آن روز مرا خواهند گفت: “خداوندا، خداوندا، آیا به نام تو نبوت ننمودیم و به اسم تو دیوها را اخراج نکردیم و به نام تو معجزات بسیار ظاهرنساختیم؟”"},{"v":23,"t":"آنگاه به ایشان صریح خواهم گفت که “هرگز شما را نشناختم! ای بدکاران از من دور شوید!”"},{"v":24,"t":"«پس هر‌که این سخنان مرا بشنود و آنها رابه‌جا آرد، او را به مردی دانا تشبیه می‌کنم که خانه خود را بر سنگ بنا کرد."},{"v":25,"t":"و باران باریده، سیلابهاروان گردید و بادها وزیده، بدان خانه زورآور شدو خراب نگردید زیرا که بر سنگ بنا شده بود."},{"v":26,"t":"وهر‌که این سخنان مرا شنیده، به آنها عمل نکرد، به مردی نادان ماند که خانه خود را بر ریگ بنا نهاد."},{"v":27,"t":"و باران باریده، سیلابها جاری شد و بادهاوزیده، بدان خانه زور آورد و خراب گردید وخرابی آن عظیم بود.»"},{"v":28,"t":"و چون عیسی این سخنان را ختم کرد آن گروه از تعلیم او در حیرت افتادند،"},{"v":29,"t":"زیرا که ایشان را چون صاحب قدرت تعلیم می‌داد و نه مثل کاتبان."}],"en":[{"v":1,"t":"“Don’t judge, so that you won’t be judged."},{"v":2,"t":"For with whatever judgment you judge, you will be judged; and with whatever measure you measure, it will be measured to you."},{"v":3,"t":"Why do you see the speck that is in your brother’s eye, but don’t consider the beam that is in your own eye?"},{"v":4,"t":"Or how will you tell your brother, ‘Let me remove the speck from your eye,’ and behold, the beam is in your own eye?"},{"v":5,"t":"You hypocrite! First remove the beam out of your own eye, and then you can see clearly to remove the speck out of your brother’s eye."},{"v":6,"t":"“Don’t give that which is holy to the dogs, neither throw your pearls before the pigs, lest perhaps they trample them under their feet, and turn and tear you to pieces."},{"v":7,"t":"“Ask, and it will be given you. Seek, and you will find. Knock, and it will be opened for you."},{"v":8,"t":"For everyone who asks receives. He who seeks finds. To him who knocks it will be opened."},{"v":9,"t":"Or who is there among you who, if his son asks him for bread, will give him a stone?"},{"v":10,"t":"Or if he asks for a fish, who will give him a serpent?"},{"v":11,"t":"If you then, being evil, know how to give good gifts to your children, how much more will your Father who is in heaven give good things to those who ask him!"},{"v":12,"t":"Therefore, whatever you desire for men to do to you, you shall also do to them; for this is the law and the prophets."},{"v":13,"t":"“Enter in by the narrow gate; for the gate is wide and the way is broad that leads to destruction, and there are many who enter in by it."},{"v":14,"t":"How narrow is the gate and the way is restricted that leads to life! There are few who find it."},{"v":15,"t":"“Beware of false prophets, who come to you in sheep’s clothing, but inwardly are ravening wolves."},{"v":16,"t":"By their fruits you will know them. Do you gather grapes from thorns or figs from thistles?"},{"v":17,"t":"Even so, every good tree produces good fruit, but the corrupt tree produces evil fruit."},{"v":18,"t":"A good tree can’t produce evil fruit, neither can a corrupt tree produce good fruit."},{"v":19,"t":"Every tree that doesn’t grow good fruit is cut down and thrown into the fire."},{"v":20,"t":"Therefore by their fruits you will know them."},{"v":21,"t":"“Not everyone who says to me, ‘Lord, Lord,’ will enter into the Kingdom of Heaven, but he who does the will of my Father who is in heaven."},{"v":22,"t":"Many will tell me in that day, ‘Lord, Lord, didn’t we prophesy in your name, in your name cast out demons, and in your name do many mighty works?’"},{"v":23,"t":"Then I will tell them, ‘I never knew you. Depart from me, you who work iniquity.’"},{"v":24,"t":"“Everyone therefore who hears these words of mine and does them, I will liken him to a wise man who built his house on the rock."},{"v":25,"t":"The rain came down, the floods came, and the winds blew and beat on that house; and it didn’t fall, for it was founded on the rock."},{"v":26,"t":"Everyone who hears these words of mine and doesn’t do them will be like a foolish man who built his house on the sand."},{"v":27,"t":"The rain came down, the floods came, and the winds blew and beat on that house; and it fell—and its fall was great.”"},{"v":28,"t":"When Jesus had finished saying these things, the multitudes were astonished at his teaching,"},{"v":29,"t":"for he taught them with authority, and not like the scribes."}],"hr":[{"v":1,"t":"“Ne sudite da ne budete suđeni!"},{"v":2,"t":"Jer sudom kojim sudite bit ćete suđeni. I mjerom kojom mjerite mjerit će vam se."},{"v":3,"t":"Što gledaš trun u oku brata svojega, a brvna u oku svome ne opažaš?"},{"v":4,"t":"Ili kako možeš reći bratu svomu: 'De da ti izvadim trun iz oka', a eto brvna u oku tvom?"},{"v":5,"t":"Licemjere, izvadi najprije brvno iz oka svoga pa ćeš onda dobro vidjeti izvaditi trun iz oka bratova!”"},{"v":6,"t":"“Ne dajte svetinje psima! Niti svoga biserja bacajte pred svinje da ga ne pogaze nogama pa se okrenu i rastrgaju vas.”"},{"v":7,"t":"“Ištite i dat će vam se! Tražite i naći ćete! Kucajte i otvorit će vam se!"},{"v":8,"t":"Doista, tko god ište, prima; i tko traži, nalazi; i onomu koji kuca otvorit će se."},{"v":9,"t":"Ta ima li koga među vama da bi svojemu sinu, ako ga zaište kruha, kamen dao?"},{"v":10,"t":"Ili ako ribu zaište, zar će mu zmiju dati?"},{"v":11,"t":"Ako dakle vi, iako zli, znate dobrim darima darivati djecu svoju, koliko li će više Otac vaš, koji je na nebesima, dobrima obdariti one koji ga zaištu!”"},{"v":12,"t":"“Sve, dakle, što želite da ljudi vama čine, činite i vi njima. To je, doista, Zakon i Proroci.”"},{"v":13,"t":"“Uđite na uska vrata! Jer široka su vrata i prostran put koji vodi u propast i mnogo ih je koji njime idu."},{"v":14,"t":"O kako su uska vrata i tijesan put koji vodi u Život i malo ih je koji ga nalaze!”"},{"v":15,"t":"“Čuvajte se lažnih proroka koji dolaze k vama u ovčjem odijelu, a iznutra su vuci grabežljivi."},{"v":16,"t":"Po njihovim ćete ih plodovima prepoznati. Bere li se s trnja grožđe ili s bodljike smokve?"},{"v":17,"t":"Tako svako dobro stablo rađa dobrim plodovima, a nevaljalo stablo rađa plodovima zlim."},{"v":18,"t":"Ne može dobro stablo donijeti zlih plodova niti nevaljalo stablo dobrih plodova."},{"v":19,"t":"Svako stablo koje ne rađa dobrim plodom siječe se i u oganj baca."},{"v":20,"t":"Dakle: po plodovima ćete ih njihovim prepoznati.”"},{"v":21,"t":"“Neće u kraljevstvo nebesko ući svaki koji mi govori: 'Gospodine, Gospodine!', nego onaj koji vrši volju Oca mojega, koji je na nebesima."},{"v":22,"t":"Mnogi će me u onaj dan pitati: 'Gospodine, Gospodine! Nismo li mi u tvoje ime prorokovali, u tvoje ime đavle izgonili, u tvoje ime mnoga čudesa činili?'"},{"v":23,"t":"Tada ću im kazati: 'Nikad vas nisam poznavao! Nosite se od mene, vi bezakonici!'”"},{"v":24,"t":"“Stoga, tko god sluša ove moje riječi i izvršava ih, bit će kao mudar čovjek koji sagradi kuću na stijeni."},{"v":25,"t":"Zapljušti kiša, navale bujice, duhnu vjetrovi i sruče se na tu kuću, ali ona ne pada. Jer - utemeljena je na stijeni.”"},{"v":26,"t":"“Naprotiv, tko god sluša ove moje riječi, a ne vrši ih, bit će kao lud čovjek koji sagradi kuću na pijesku."},{"v":27,"t":"Zapljušti kiša, navale bujice, duhnu vjetrovi i sruče se na tu kuću i ona se sruši. I bijaše to ruševina velika.”"},{"v":28,"t":"Kad Isus završi ove svoje besjede, mnoštvo osta zaneseno njegovim naukom."},{"v":29,"t":"Ta učio ih kao onaj koji ima vlast, a ne kao njihovi pismoznanci."}]},"8":{"fa":[{"v":1,"t":"و چون او از کوه به زیر آمد، گروهی بسیاراز عقب او روانه شدند."},{"v":2,"t":"که ناگاه ابرصی آمد و او را پرستش نموده، گفت: «ای خداوند اگربخواهی، می‌توانی مرا طاهر سازی.»"},{"v":3,"t":"عیسی دست آورده، او را لمس نمود و گفت: «می‌خواهم؛ طاهر شو!» که فور برص او طاهرگشت."},{"v":4,"t":"عیسی بدو گفت: «زنهار کسی را اطلاع ندهی بلکه رفته، خود را به کاهن بنما و آن هدیه‌ای را که موسی فرمود، بگذران تا بجهت ایشان شهادتی باشد.»"},{"v":5,"t":"و چون عیسی وارد کفرناحوم شد، یوزباشی‌ای نزد وی آمد و بدو التماس نموده،"},{"v":6,"t":"گفت: «ای خداوند، خادم من مفلوج در خانه خوابیده و بشدت متالم است.»"},{"v":7,"t":"عیسی بدو گفت: «من آمده، او را شفا خواهم داد.»"},{"v":8,"t":"یوزباشی در جواب گفت: «خداوندا، لایق آن نی‌ام که زیرسقف من آیی. بلکه فقط سخنی بگو و خادم من صحت خواهد یافت."},{"v":9,"t":"زیرا که من نیز مردی زیرحکم هستم و سپاهیان را زیر دست خود دارم؛ چون به یکی گویم برو، می‌رود و به دیگری بیا، می‌آید و به غلام خود فلان کار را بکن، می‌کند.»"},{"v":10,"t":"عیسی چون این سخن را شنید، متعجب شده، به همراهان خود گفت: «هرآینه به شما می‌گویم که چنین ایمانی در اسرائیل هم نیافته‌ام."},{"v":11,"t":"و به شما می‌گویم که بسا از مشرق و مغرب آمده، درملکوت آسمان با ابراهیم و اسحاق و یعقوب خواهند نشست؛"},{"v":12,"t":"اما پسران ملکوت بیرون افکنده خواهند شد، در ظلمت خارجی جایی که گریه و فشار دندان باشد."},{"v":13,"t":"پس عیسی به یوزباشی گفت: «برو، بر وفق ایمانت تو را عطاشود، » که در ساعت خادم او صحت یافت."},{"v":14,"t":"و چون عیسی به خانه پطرس آمد، مادر‌زن او را دید که تب کرده، خوابیده است."},{"v":15,"t":"پس دست او را لمس کرد و تب او را رها کرد. پس برخاسته، به خدمت گذاری ایشان مشغول گشت."},{"v":16,"t":"اما چون شام شد، بسیاری از دیوانگان را به نزداو آوردند و محض سخنی ارواح را بیرون کرد وهمه مریضان را شفا بخشید."},{"v":17,"t":"تا سخنی که به زبان اشعیای نبی گفته شده بود تمام گردد که «او ضعف های ما را گرفت و مرض های ما رابرداشت.»"},{"v":18,"t":"چون عیسی جمعی کثیر دور خود دید، فرمان داد تا به کناره دیگر روند."},{"v":19,"t":"آنگاه کاتبی پیش آمده، بدو گفت: «استادا هرجا روی، تو رامتابعت کنم.»"},{"v":20,"t":"عیسی بدو گفت: «روباهان راسوراخها و مرغان هوا را آشیانه‌ها است. لیکن پسر انسان را جای سر نهادن نیست.»"},{"v":21,"t":"و دیگری از شاگردانش بدو گفت: «خداوندا اول مرارخصت ده تا رفته، پدر خود را دفن کنم.»"},{"v":22,"t":"عیسی وی را گفت: «مرا متابعت کن و بگذار که مردگان، مردگان خود را دفن کنند.»"},{"v":23,"t":"چون به کشتی سوار شد، شاگردانش ازعقب او آمدند."},{"v":24,"t":"ناگاه اضطراب عظیمی در دریاپدید آمد، بحدی که امواج، کشتی را فرومی گرفت؛ و او در خواب بود."},{"v":25,"t":"پس شاگردان پیش آمده، او را بیدار کرده، گفتند: «خداوندا، مارا دریاب که هلاک می‌شویم!»"},{"v":26,"t":"بدیشان گفت: «ای کم‌ایمانان، چرا ترسان هستید؟» آنگاه برخاسته، بادها و دریا را نهیب کرد که آرامی کامل پدید آمد."},{"v":27,"t":"اما آن اشخاص تعجب نموده، گفتند: «این چگونه مردی است که بادها و دریا نیزاو را اطاعت می‌کنند!»"},{"v":28,"t":"و چون به آن کناره در زمین جرجسیان رسید، دو شخص دیوانه از قبرها بیرون شده، بدوبرخوردند و بحدی تندخوی بودند که هیچ‌کس از آن راه نتوانستی عبور کند."},{"v":29,"t":"در ساعت فریادکرده، گفتند: «یا عیسی ابن‌الله، ما را با تو جه کار است؟ مگر در اینجا آمده‌ای تا ما را قبل از وقت عذاب کنی؟”"},{"v":30,"t":"و گلۀگراز بسیاری دور از ایشان می‌چرید."},{"v":31,"t":"دیوها از وی استدعا نموده، گفتند: “هرگاه ما را بیرون کنی، در گلۀ گرازان ما را بفرست.”"},{"v":32,"t":"ایشان را گفت: “بروید!” در حال بیرون شده، داخل گلۀ گرازان گردیدند که فی‌الفور همۀ آن گرازان از بلندی به دریا جسته، در آب هلاک شدند."},{"v":33,"t":"اما شبانان گریخته، به شهر رفتند و تمام آن حادثه و ماجرای دیوانگان را شهرت دادند."},{"v":34,"t":"واینک تمام شهر برای ملاقات عیسی بیرون آمد. چون او را دیدند، التماس نمودند که از حدودایشان بیرون رود."}],"en":[{"v":1,"t":"When he came down from the mountain, great multitudes followed him."},{"v":2,"t":"Behold, a leper came to him and worshiped him, saying, “Lord, if you want to, you can make me clean.”"},{"v":3,"t":"Jesus stretched out his hand and touched him, saying, “I want to. Be made clean.” Immediately his leprosy was cleansed."},{"v":4,"t":"Jesus said to him, “See that you tell nobody; but go, show yourself to the priest, and offer the gift that Moses commanded, as a testimony to them.”"},{"v":5,"t":"When he came into Capernaum, a centurion came to him, asking him for help,"},{"v":6,"t":"saying, “Lord, my servant lies in the house paralyzed, grievously tormented.”"},{"v":7,"t":"Jesus said to him, “I will come and heal him.”"},{"v":8,"t":"The centurion answered, “Lord, I’m not worthy for you to come under my roof. Just say the word, and my servant will be healed."},{"v":9,"t":"For I am also a man under authority, having under myself soldiers. I tell this one, ‘Go,’ and he goes; and tell another, ‘Come,’ and he comes; and tell my servant, ‘Do this,’ and he does it.”"},{"v":10,"t":"When Jesus heard it, he marveled and said to those who followed, “Most certainly I tell you, I haven’t found so great a faith, not even in Israel."},{"v":11,"t":"I tell you that many will come from the east and the west, and will sit down with Abraham, Isaac, and Jacob in the Kingdom of Heaven,"},{"v":12,"t":"but the children of the Kingdom will be thrown out into the outer darkness. There will be weeping and gnashing of teeth.”"},{"v":13,"t":"Jesus said to the centurion, “Go your way. Let it be done for you as you have believed.” His servant was healed in that hour."},{"v":14,"t":"When Jesus came into Peter’s house, he saw his wife’s mother lying sick with a fever."},{"v":15,"t":"He touched her hand, and the fever left her. So she got up and served him."},{"v":16,"t":"When evening came, they brought to him many possessed with demons. He cast out the spirits with a word, and healed all who were sick,"},{"v":17,"t":"that it might be fulfilled which was spoken through Isaiah the prophet, saying, “He took our infirmities and bore our diseases.”"},{"v":18,"t":"Now when Jesus saw great multitudes around him, he gave the order to depart to the other side."},{"v":19,"t":"A scribe came and said to him, “Teacher, I will follow you wherever you go.”"},{"v":20,"t":"Jesus said to him, “The foxes have holes and the birds of the sky have nests, but the Son of Man has nowhere to lay his head.”"},{"v":21,"t":"Another of his disciples said to him, “Lord, allow me first to go and bury my father.”"},{"v":22,"t":"But Jesus said to him, “Follow me, and leave the dead to bury their own dead.”"},{"v":23,"t":"When he got into a boat, his disciples followed him."},{"v":24,"t":"Behold, a violent storm came up on the sea, so much that the boat was covered with the waves; but he was asleep."},{"v":25,"t":"The disciples came to him and woke him up, saying, “Save us, Lord! We are dying!”"},{"v":26,"t":"He said to them, “Why are you fearful, O you of little faith?” Then he got up, rebuked the wind and the sea, and there was a great calm."},{"v":27,"t":"The men marveled, saying, “What kind of man is this, that even the wind and the sea obey him?”"},{"v":28,"t":"When he came to the other side, into the country of the Gergesenes, two people possessed by demons met him there, coming out of the tombs, exceedingly fierce, so that nobody could pass that way."},{"v":29,"t":"Behold, they cried out, saying, “What do we have to do with you, Jesus, Son of God? Have you come here to torment us before the time?”"},{"v":30,"t":"Now there was a herd of many pigs feeding far away from them."},{"v":31,"t":"The demons begged him, saying, “If you cast us out, permit us to go away into the herd of pigs.”"},{"v":32,"t":"He said to them, “Go!” They came out and went into the herd of pigs; and behold, the whole herd of pigs rushed down the cliff into the sea and died in the water."},{"v":33,"t":"Those who fed them fled and went away into the city and told everything, including what happened to those who were possessed with demons."},{"v":34,"t":"Behold, all the city came out to meet Jesus. When they saw him, they begged that he would depart from their borders."}],"hr":[{"v":1,"t":"Kad je Isus sišao s gore, pohrli za njim silan svijet."},{"v":2,"t":"I gle, pristupi neki gubavac, pokloni mu se do zemlje i reče: “Gospodine, ako hoćeš, možeš me očistiti.”"},{"v":3,"t":"Isus pruži ruku i dotakne ga se govoreći: “Hoću, očisti se!” I odmah se očisti od gube."},{"v":4,"t":"Kaže mu Isus: “Pazi, nikomu ne kazuj, nego idi, pokaži se svećeniku i prinesi dar što ga propisa Mojsije, njima za svjedočanstvo.”"},{"v":5,"t":"Kad uđe u Kafarnaum, pristupi mu satnik pa ga zamoli:"},{"v":6,"t":"“Gospodine, sluga mi leži kod kuće uzet, u strašnim mukama.”"},{"v":7,"t":"Kaže mu: “Ja ću doći izliječiti ga.”"},{"v":8,"t":"Odgovori satnik: “Gospodine, nisam dostojan da uđeš pod krov moj, nego samo reci riječ i izliječen će biti sluga moj."},{"v":9,"t":"Ta i ja, premda sam čovjek pod vlašću, imam pod sobom vojnike pa reknem jednomu: 'Idi!' - i ode, drugomu: 'Dođi!' - i dođe, a sluzi svomu: 'Učini to' - i učini.”"},{"v":10,"t":"Čuvši to, zadivi se Isus i reče onima koji su išli za njim: “Zaista, kažem vam, ni u koga u Izraelu ne nađoh tolike vjere."},{"v":11,"t":"A kažem vam: Mnogi će s istoka i zapada doći i sjesti za stol s Abrahamom, Izakom i Jakovom u kraljevstvu nebeskom,"},{"v":12,"t":"a sinovi će kraljevstva biti izbačeni van u tamu. Ondje će biti plač i škrgut zubi.”"},{"v":13,"t":"I reče Isus satniku: “Idi, neka ti bude kako si vjerovao!” I ozdravi sluga u taj čas."},{"v":14,"t":"Ušavši u kuću Petrovu, Isus ugleda njegovu punicu koja ležaše u ognjici."},{"v":15,"t":"Dotače joj se ruke i pusti je ognjica. Ona ustade i posluživaše mu."},{"v":16,"t":"A uvečer mu doniješe mnoge opsjednute. On izagna duhove riječju i sve bolesnike ozdravi -"},{"v":17,"t":"da se ispuni što je rečeno po Izaiji proroku: On slabosti naše uze i boli ponese."},{"v":18,"t":"Kad Isus vidje mnoštvo oko sebe, zapovjedi da se prijeđe prijeko."},{"v":19,"t":"I pristupi jedan pismoznanac te mu reče: “Učitelju, za tobom ću kamo god ti pošao.”"},{"v":20,"t":"Kaže mu Isus: “Lisice imaju jazbine i ptice nebeske gnijezda, a Sin Čovječji nema gdje bi glavu naslonio.”"},{"v":21,"t":"Drugi mu od učenika reče: “Gospodine, dopusti mi da prije odem i pokopam svoga oca.”"},{"v":22,"t":"Isus mu kaže: “Hajde za mnom i pusti neka mrtvi pokapaju svoje mrtve.”"},{"v":23,"t":"Kad uđe u lađu, pođoše za njim njegovi učenici."},{"v":24,"t":"I gle, žestok vihor nasta na moru tako da lađu prekrivahu valovi. A on je spavao."},{"v":25,"t":"Oni pristupiše i probudiše ga govoreći: “Gospodine, spasi, pogibosmo!”"},{"v":26,"t":"Kaže im: “Što ste plašljivi, malovjerni?” Tada ustade i zaprijeti vjetrovima i moru te nasta velika utiha."},{"v":27,"t":"A ljudi su u čudu pitali: “Tko je taj da mu se i vjetrovi i more pokoravaju?”"},{"v":28,"t":"I kada dođe prijeko, u gadarski kraj, eto mu u susret dvaju opsjednutih: izlazili su iz grobnica, silno goropadni, te nitko nije mogao proći onim putem."},{"v":29,"t":"I gle, povikaše: “Što ti imaš s nama, Sine Božji? Došao si ovamo prije vremena mučiti nas?”"},{"v":30,"t":"A podalje od njih paslo je veliko krdo svinja."},{"v":31,"t":"Zlodusi ga zaklinjahu: “Ako nas istjeraš, pošalji nas u ovo krdo svinja.”"},{"v":32,"t":"On im reče: “Idite!” Oni iziđoše i uđoše u svinje. I gle, sve krdo jurnu niz obronak u more i podavi se u vodama."},{"v":33,"t":"A svinjari pobjegoše, odoše u grad te razglasiše sve, napose o opsjednutima."},{"v":34,"t":"I gle, sav grad iziđe u susret Isusu. Kad ga ugledaše, zamole ga da ode iz njihova kraja."}]},"9":{"fa":[{"v":1,"t":"پس به کشتی سوار شده، عبور کرد و به شهر خویش آمد."},{"v":2,"t":"ناگاه مفلوجی را بر بستر خوابانیده، نزد وی آوردند. چون عیسی ایمان ایشان را دید، مفلوج را گفت: «ای فرزند، خاطر جمع دار که گناهانت آمرزیده شد.»"},{"v":3,"t":"آنگاه بعضی از کاتبان با خود گفتند: «این شخص کفر می‌گوید.»"},{"v":4,"t":"عیسی خیالات ایشان رادرک نموده، گفت: «از بهر‌چه خیالات فاسد به‌خاطر خود راه می‌دهید؟"},{"v":5,"t":"زیرا کدام سهل تراست، گفتن اینکه گناهان تو آمرزیده شد یا گفتن آنکه برخاسته بخرام؟"},{"v":6,"t":"لیکن تا بدانید که پسرانسان را قدرت آمرزیدن گناهان بر روی زمین هست...» آنگاه مفلوج را گفت: «برخیز و بسترخود را برداشته، به خانه خود روانه شو!»"},{"v":7,"t":"درحال برخاسته، به خانه خود رفت!"},{"v":8,"t":"و آن گروه چون این عمل را دیدند، متعجب شده، خدایی راکه این نوع قدرت به مردم عطا فرموده بود، تمجیدنمودند."},{"v":9,"t":"چون عیسی از آنجا می‌گذشت، مردی رامسمی به متی به باج گاه نشسته دید. بدو گفت: «مرا متابعت کن.» در حال برخاسته، از عقب وی روانه شد."},{"v":10,"t":"و واقع شد چون او در خانه به غذا نشسته بود که جمعی از باجگیران وگناهکاران آمده، با عیسی و شاگردانش بنشستند."},{"v":11,"t":"«و فریسیان چون دیدند، به شاگردان اوگفتند: «چرا استاد شما با باجگیران وگناهکاران غذا می‌خورد؟»"},{"v":12,"t":"عیسی چون شنید، گفت: «نه تندرستان بلکه مریضان احتیاج به طبیب دارند."},{"v":13,"t":"لکن رفته، این را دریافت کنید که “رحمت می‌خواهم نه قربانی “، زیرا نیامده‌ام تاعادلان را بلکه گناهکاران را به توبه دعوت نمایم.»"},{"v":14,"t":"آنگاه شاگردان یحیی نزد وی آمده، گفتند: «چون است که ما و فریسیان روزه بسیارمی داریم، لکن شاگردان تو روزه نمی دارند؟»"},{"v":15,"t":"عیسی بدیشان گفت: «آیا پسران خانه عروسی، مادامی که داماد با ایشان است، می‌توانند ماتم کنند؟ و لکن ایامی می‌آید که داماد از ایشان گرفته شود؛ در آن هنگام روزه خواهند داشت."},{"v":16,"t":"وهیچ‌کس بر جامه کهنه پاره‌ای از پارچه نو وصله نمی کند زیرا که آن وصله از جامه جدا می‌گردد ودریدگی بدتر می‌شود."},{"v":17,"t":"و شراب نو را درمشکهای کهنه نمی ریزند والا مشکها دریده شده، شراب ریخته و مشکها تباه گردد. بلکه شراب نو را در مشکهای نو می‌ریزند تا هر دومحفوظ باشد.»"},{"v":18,"t":"او هنوز این سخنان را بدیشان می‌گفت که ناگاه رئیسی آمد و او را پرستش نموده، گفت: «اکنون دختر من مرده است. لکن بیا و دست خودرا بر وی گذار که زیست خواهد کرد.»"},{"v":19,"t":"پس عیسی به اتفاق شاگردان خود برخاسته، از عقب او روان شد."},{"v":20,"t":"و اینک زنی که مدت دوازده سال به مرض استحاضه مبتلا می‌بود، از عقب او آمده، دامن ردای او را لمس نمود،"},{"v":21,"t":"زیرا با خود گفته بود: «اگر محض ردایش را لمس کنم، هرآینه شفایابم.»"},{"v":22,"t":"عیسی برگشته، نظر بر وی انداخته، گفت: «ای دختر، خاطرجمع باش زیرا که ایمانت تو را شفا داده است!» در ساعت آن زن رستگارگردید."},{"v":23,"t":"و چون عیسی به خانه رئیس در‌آمد، نوحه‌گران و گروهی از شورش کنندگان را دیده،"},{"v":24,"t":"بدیشان گفت: «راه دهید، زیرا دختر نمرده بلکه در خواب است.» ایشان بر وی سخریه کردند."},{"v":25,"t":"اما چون آن گروه بیرون شدند، داخل شده، دست آن دختر را گرفت که در ساعت برخاست."},{"v":26,"t":"و این کار در تمام آن مرز وبوم شهرت یافت."},{"v":27,"t":"و چون عیسی از آن مکان می‌رفت، دو کورفریاد‌کنان در عقب او افتاده، گفتند: «پسر داودا، بر ما ترحم کن!»"},{"v":28,"t":"و چون به خانه در‌آمد، آن دوکور نزد او آمدند. عیسی بدیشان گفت: «آیا ایمان دارید که این کار را می‌توانم کرد؟» گفتندش: «بلی خداوندا.»"},{"v":29,"t":"در ساعت چشمان ایشان را لمس کرده، گفت: «بر وفق ایمانتان به شما بشود.»"},{"v":30,"t":"درحال چشمانشان باز شد و عیسی ایشان را به تاکیدفرمود که «زنهار کسی اطلاع نیابد.»"},{"v":31,"t":"اما ایشان بیرون رفته، او را در تمام آن نواحی شهرت دادند."},{"v":32,"t":"و هنگامی که ایشان بیرون می‌رفتند، ناگاه دیوانه‌ای گنگ را نزد او آوردند."},{"v":33,"t":"و چون دیوبیرون شد، گنگ، گویا گردید و همه در تعجب شده، گفتند: «در اسرائیل چنین امر هرگز دیده نشده بود.»"},{"v":34,"t":"لیکن فریسیان گفتند: «به واسطه رئیس دیوها، دیوها را بیرون می‌کند.»"},{"v":35,"t":"و عیسی در همه شهرها و دهات گشته، در کنایس ایشان تعلیم داده، به بشارت ملکوت موعظه می‌نمود و هر مرض و رنج مردم را شفامی داد."},{"v":36,"t":"و چون جمع کثیر دید، دلش بر ایشان بسوخت زیرا که مانند گوسفندان بی‌شبان، پریشان حال و پراکنده بودند."},{"v":37,"t":"آنگاه به شاگردان خود گفت: «حصاد فراوان است لیکن عمله کم. پس از صاحب حصاد استدعا نمایید تاعمله در حصاد خود بفرستد.»"}],"en":[{"v":1,"t":"He entered into a boat and crossed over, and came into his own city."},{"v":2,"t":"Behold, they brought to him a man who was paralyzed, lying on a bed. Jesus, seeing their faith, said to the paralytic, “Son, cheer up! Your sins are forgiven you.”"},{"v":3,"t":"Behold, some of the scribes said to themselves, “This man blasphemes.”"},{"v":4,"t":"Jesus, knowing their thoughts, said, “Why do you think evil in your hearts?"},{"v":5,"t":"For which is easier, to say, ‘Your sins are forgiven;’ or to say, ‘Get up, and walk’?"},{"v":6,"t":"But that you may know that the Son of Man has authority on earth to forgive sins—” (then he said to the paralytic), “Get up, and take up your mat, and go to your house.”"},{"v":7,"t":"He arose and departed to his house."},{"v":8,"t":"But when the multitudes saw it, they marveled and glorified God, who had given such authority to men."},{"v":9,"t":"As Jesus passed by from there, he saw a man called Matthew sitting at the tax collection office. He said to him, “Follow me.” He got up and followed him."},{"v":10,"t":"As he sat in the house, behold, many tax collectors and sinners came and sat down with Jesus and his disciples."},{"v":11,"t":"When the Pharisees saw it, they said to his disciples, “Why does your teacher eat with tax collectors and sinners?”"},{"v":12,"t":"When Jesus heard it, he said to them, “Those who are healthy have no need for a physician, but those who are sick do."},{"v":13,"t":"But you go and learn what this means: ‘I desire mercy, and not sacrifice,’ for I came not to call the righteous, but sinners to repentance.”"},{"v":14,"t":"Then John’s disciples came to him, saying, “Why do we and the Pharisees fast often, but your disciples don’t fast?”"},{"v":15,"t":"Jesus said to them, “Can the friends of the bridegroom mourn as long as the bridegroom is with them? But the days will come when the bridegroom will be taken away from them, and then they will fast."},{"v":16,"t":"No one puts a piece of unshrunk cloth on an old garment; for the patch would tear away from the garment, and a worse hole is made."},{"v":17,"t":"Neither do people put new wine into old wineskins, or else the skins would burst, and the wine be spilled, and the skins ruined. No, they put new wine into fresh wineskins, and both are preserved.”"},{"v":18,"t":"While he told these things to them, behold, a ruler came and worshiped him, saying, “My daughter has just died, but come and lay your hand on her, and she will live.”"},{"v":19,"t":"Jesus got up and followed him, as did his disciples."},{"v":20,"t":"Behold, a woman who had a discharge of blood for twelve years came behind him, and touched the fringe of his garment;"},{"v":21,"t":"for she said within herself, “If I just touch his garment, I will be made well.”"},{"v":22,"t":"But Jesus, turning around and seeing her, said, “Daughter, cheer up! Your faith has made you well.” And the woman was made well from that hour."},{"v":23,"t":"When Jesus came into the ruler’s house and saw the flute players and the crowd in noisy disorder,"},{"v":24,"t":"he said to them, “Make room, because the girl isn’t dead, but sleeping.” They were ridiculing him."},{"v":25,"t":"But when the crowd was sent out, he entered in, took her by the hand, and the girl arose."},{"v":26,"t":"The report of this went out into all that land."},{"v":27,"t":"As Jesus passed by from there, two blind men followed him, calling out and saying, “Have mercy on us, son of David!”"},{"v":28,"t":"When he had come into the house, the blind men came to him. Jesus said to them, “Do you believe that I am able to do this?” They told him, “Yes, Lord.”"},{"v":29,"t":"Then he touched their eyes, saying, “According to your faith be it done to you.”"},{"v":30,"t":"Then their eyes were opened. Jesus strictly commanded them, saying, “See that no one knows about this.”"},{"v":31,"t":"But they went out and spread abroad his fame in all that land."},{"v":32,"t":"As they went out, behold, a mute man who was demon possessed was brought to him."},{"v":33,"t":"When the demon was cast out, the mute man spoke. The multitudes marveled, saying, “Nothing like this has ever been seen in Israel!”"},{"v":34,"t":"But the Pharisees said, “By the prince of the demons, he casts out demons.”"},{"v":35,"t":"Jesus went about all the cities and the villages, teaching in their synagogues and preaching the Good News of the Kingdom, and healing every disease and every sickness among the people."},{"v":36,"t":"But when he saw the multitudes, he was moved with compassion for them because they were harassed and scattered, like sheep without a shepherd."},{"v":37,"t":"Then he said to his disciples, “The harvest indeed is plentiful, but the laborers are few."},{"v":38,"t":"Pray therefore that the Lord of the harvest will send out laborers into his harvest.”"}],"hr":[{"v":1,"t":"I ušavši u lađu, preplovi i dođe u svoj grad."},{"v":2,"t":"Kad gle, doniješe mu uzetoga koji je ležao na nosiljci. Vidjevši njihovu vjeru, reče Isus uzetomu: “Hrabro, sinko, otpuštaju ti se grijesi!”"},{"v":3,"t":"A gle, neki od pismoznanaca rekoše u sebi: “Ovaj huli!”"},{"v":4,"t":"Prozrevši njihove misli, Isus reče: “Zašto snujete zlo u srcima?"},{"v":5,"t":"Ta što je lakše reći: 'Otpuštaju ti se grijesi' ili reći: 'Ustani i hodi'?"},{"v":6,"t":"Ali da znate: vlastan je Sin Čovječji na zemlji otpuštati grijehe!” Tada reče uzetomu: “Ustani, uzmi nosiljku i pođi kući!”"},{"v":7,"t":"I on usta te ode kući."},{"v":8,"t":"Kad mnoštvo to vidje, zaprepasti se i poda slavu Bogu koji takvu vlast dade ljudima."},{"v":9,"t":"Odlazeći odande, ugleda Isus čovjeka zvanog Matej gdje sjedi u carinarnici. I kaže mu: “Pođi za mnom!” On usta i pođe za njim."},{"v":10,"t":"Dok je Isus bio u kući za stolom, gle, mnogi carinici i grešnici dođoše za stol s njime i njegovim učenicima."},{"v":11,"t":"Vidjevši to, farizeji stanu govoriti: “Zašto vaš učitelj jede s carinicima i grešnicima?”"},{"v":12,"t":"A on, čuvši to, reče: “Ne treba zdravima liječnika, nego bolesnima."},{"v":13,"t":"Hajdete i proučite što znači: Milosrđe mi je milo, a ne žrtva. Ta ne dođoh zvati pravednike, nego grešnike.”"},{"v":14,"t":"Tada pristupe k njemu Ivanovi učenici govoreći: “Zašto mi i farizeji postimo, a učenici tvoji ne poste?”"},{"v":15,"t":"Nato im Isus reče: “Mogu li svatovi tugovati dok je s njima zaručnik? Doći će već dani kad će im se ugrabiti zaručnik, i tada će postiti!”"},{"v":16,"t":"“A nitko ne stavlja krpe od sirova sukna na staro odijelo, jer zakrpa vuče s odijela pa nastane još veća rupa.”"},{"v":17,"t":"“I ne ulijeva se novo vino u stare mješine. Inače se mješine proderu, vino prolije, a mješine propadnu. Nego, novo se vino ulijeva u nove mješine pa se oboje sačuva.”"},{"v":18,"t":"Dok im on to govoraše, gle, pristupi neki glavar, pokloni mu se do zemlje i reče: “Kći mi, evo, umrije, ali dođi, stavi ruku na nju, i oživjet će.”"},{"v":19,"t":"Isus usta te s učenicima pođe za njim."},{"v":20,"t":"I gle, neka žena koja bolovaše dvanaest godina od krvarenja priđe odostraga i dotaknu se skuta njegove haljine."},{"v":21,"t":"Mislila je: “Dotaknem li se samo njegove haljine, spasit ću se.”"},{"v":22,"t":"A Isus se okrenu i vidjevši je reče: “Hrabro, kćeri, vjera te tvoja spasila.” I žena bi spašena od toga časa."},{"v":23,"t":"I uđe Isus u kuću glavarovu. Ugleda svirače i bučno mnoštvo pa"},{"v":24,"t":"reče: “Odstupite! Djevojka nije umrla, nego spava.” Oni mu se podsmjehivahu."},{"v":25,"t":"A kad je svijet bio izbačen, uđe on, primi djevojku za ruku i ona bi uskrišena."},{"v":26,"t":"I razglasi se to po svem onom kraju."},{"v":27,"t":"Kad je Isus odlazio odande, pođu za njim dva slijepca vičući: “Smiluj nam se, Sine Davidov!”"},{"v":28,"t":"A kad uđe u kuću, pristupe mu slijepci. Isus im kaže: “Vjerujete li da mogu to učiniti?” Kažu mu: “Da, Gospodine!”"},{"v":29,"t":"Tada se dotače njihovih očiju govoreći: “Neka vam bude po vašoj vjeri.”"},{"v":30,"t":"I otvoriše im se oči. A Isus im poprijeti: “Pazite da nitko ne dozna!”"},{"v":31,"t":"Ali oni, izišavši, razniješe glas o njemu po svem onom kraju."},{"v":32,"t":"Tek što oni iziđoše, gle, doniješe mu njemaka opsjednuta."},{"v":33,"t":"Pošto izagna đavla, progovori njemak. Mnoštvo se čudom čudilo i govorilo: “Nikada se takvo što ne vidje u Izraelu!”"},{"v":34,"t":"A farizeji govorahu: “Po poglavici đavolskome izgoni đavle.”"},{"v":35,"t":"I obilazio je Isus sve gradove i sela učeći po njihovim sinagogama, propovijedajući Evanđelje o Kraljevstvu i liječeći svaku bolest i svaku nemoć."},{"v":36,"t":"Vidjevši mnoštvo, sažali mu se nad njim jer bijahu izmučeni i ophrvani kao ovce bez pastira."},{"v":37,"t":"Tada reče svojim učenicima: “Žetve je mnogo, a radnika malo."},{"v":38,"t":"Molite dakle gospodara žetve da pošalje radnike u žetvu svoju.”"}]},"10":{"fa":[{"v":1,"t":"و دوازده شاگرد خود را طلبیده، ایشان را بر ارواح پلید قدرت داد که آنها رابیرون کنند و هر بیماری و رنجی را شفا دهند."},{"v":2,"t":"ونامهای دوازده رسول این است: اول شمعون معروف به پطرس و برادرش اندریاس؛ یعقوب بن زبدی و برادرش یوحنا؛"},{"v":3,"t":"فیلپس و برتولما؛ توماو متای باجگیر؛ یعقوب بن حلفی و لبی معروف به تدی؛"},{"v":4,"t":"شمعون قانوی و یهودای اسخریوطی که او را تسلیم نمود."},{"v":5,"t":"این دوازده را عیسی فرستاده، بدیشان وصیت کرده، گفت: «از راه امت‌ها مروید و دربلدی از سامریان داخل مشوید،"},{"v":6,"t":"بلکه نزدگوسفندان گم شده اسرائیل بروید."},{"v":7,"t":"و چون می‌روید، موعظه کرده، گویید که ملکوت آسمان نزدیک است."},{"v":8,"t":"بیماران را شفا دهید، ابرصان راطاهر سازید، مردگان را زنده کنید، دیوها را بیرون نمایید. مفت یافته‌اید، مفت بدهید."},{"v":9,"t":"طلا یا نقره یا مس در کمرهای خود ذخیره مکنید،"},{"v":10,"t":"و برای سفر، توشه‌دان یا دو پیراهن یا کفشها یا عصابرندارید، زیرا که مزدور مستحق خوراک خوداست."},{"v":11,"t":"و در هر شهری یا قریه‌ای که داخل شوید، بپرسید که در آنجا که لیاقت دارد؛ پس درآنجا بمانید تا بیرون روید."},{"v":12,"t":"و چون به خانه‌ای درآیید، بر آن سلام نمایید؛"},{"v":13,"t":"پس اگر خانه لایق باشد، سلام شما بر آن واقع خواهد شد و اگرنالایق بود، سلام شما به شما خواهد برگشت."},{"v":14,"t":"و هر‌که شما را قبول نکند یا به سخن شماگوش ندهد، از آن خانه یا شهر بیرون شده، خاک پایهای خود را برافشانید."},{"v":15,"t":"هرآینه به شمامی گویم که در روز جزا حالت زمین سدوم وغموره از آن شهر سهل تر خواهد بود."},{"v":16,"t":"هان، من شما را مانند گوسفندان در میان گرگان می‌فرستم؛ پس مثل مارها هوشیار و چون کبوتران ساده باشید."},{"v":17,"t":"اما از مردم برحذر باشید، زیرا که شما را به مجلسها تسلیم خواهند کرد ودر کنایس خود شما را تازیانه خواهند زد،"},{"v":18,"t":"ودر حضور حکام و سلاطین، شما را بخاطر من خواهند برد تا بر ایشان و بر امت‌ها شهادتی شود."},{"v":19,"t":"اما چون شما را تسلیم کنند، اندیشه مکنید که چگونه یا چه بگویید زیرا در همان ساعت به شماعطا خواهد شد که چه باید گفت،"},{"v":20,"t":"زیرا گوینده شما نیستید بلکه روح پدر شما، در شما گوینده است."},{"v":21,"t":"و برادر، برادر را و پدر، فرزند را به موت تسلیم خواهند کرد و فرزندان بر والدین خودبرخاسته، ایشان را به قتل خواهند رسانید؛"},{"v":22,"t":"و به جهت اسم من، جمیع مردم از شما نفرت خواهندکرد. لیکن هر‌که تا به آخر صبر کند، نجات یابد."},{"v":23,"t":"و وقتی که در یک شهر بر شما جفا کنند، به دیگری فرار کنید زیرا هرآینه به شما می‌گویم تاپسر انسان نیاید، از همه شهرهای اسرائیل نخواهید پرداخت."},{"v":24,"t":"شاگرد از معلم خود افضل نیست و نه غلام از آقایش برتر."},{"v":25,"t":"کافی است شاگرد را که چون استاد خویش گردد و غلام را که چون آقای خودشود. پس اگر صاحب‌خانه را بعلزبول خواندند، چقدر زیادتر اهل خانه‌اش را."},{"v":26,"t":"لهذا از ایشان مترسید زیرا چیزی مستور نیست که مکشوف نگردد و نه مجهولی که معلوم نشود."},{"v":27,"t":"آنچه درتاریکی به شما می‌گویم، در روشنایی بگویید، وآنچه در گوش شنوید بر بامها موعظه کنید."},{"v":28,"t":"واز قاتلان جسم که قادر بر کشتن روح نی‌اند، بیم مکنید بلکه از او بترسید که قادر است بر هلاک کردن روح و جسم را نیز در جهنم."},{"v":29,"t":"آیا دوگنجشک به یک فلس فروخته نمی شود؟ و حال آنکه یکی از آنها جز به حکم پدر شما به زمین نمی افتد."},{"v":30,"t":"لیکن همه مویهای سر شما نیزشمرده شده است."},{"v":31,"t":"پس ترسان مباشید زیراشما از گنجشکان بسیار افضل هستید."},{"v":32,"t":"پس هر‌که مرا پیش مردم اقرار کند، من نیزدر حضور پدر خود که در آسمان است، او رااقرار خواهم کرد."},{"v":33,"t":"اما هر‌که مرا پیش مردم انکار نماید، من هم در حضور پدر خود که در آسمان است او را انکار خواهم نمود."},{"v":34,"t":"گمان مبرید که آمده‌ام تا سلامتی بر زمین بگذارم. نیامده‌ام تا سلامتی بگذارم بلکه شمشیر را."},{"v":35,"t":"زیرا که آمده‌ام تا مرد را از پدر خود و دختر رااز مادر خویش و عروس را از مادر شوهرش جداسازم."},{"v":36,"t":"و دشمنان شخص، اهل خانه او خواهندبود."},{"v":37,"t":"و هر‌که پدر یا مادر را بیش از من دوست دارد؛ لایق من نباشد و هر‌که پسر یا دختر را از من زیاده دوست دارد، لایق من نباشد."},{"v":38,"t":"و هر‌که صلیب خود را برنداشته، از عقب من نیاید، لایق من نباشد."},{"v":39,"t":"هر‌که جان خود را دریابد، آن راهلاک سازد و هر‌که جان خود را بخاطر من هلاک کرد، آن را خواهد دریافت."},{"v":40,"t":"هر‌که شما را قبول کند، مرا قبول کرده و کسی‌که مرا قبول کرده، فرستنده مرا قبول کرده باشد."},{"v":41,"t":"و آنکه نبی‌ای رابه اسم نبی پذیرد، اجرت نبی یابد و هر‌که عادلی را به اسم عادلی پذیرفت، مزد عادل را خواهدیافت."},{"v":42,"t":"و هر‌که یکی از این صغار را کاسه‌ای ازآب سرد محض نام شاگرد نوشاند، هرآینه به شمامی گویم اجر خودرا ضایع نخواهد ساخت.»"}],"en":[{"v":1,"t":"He called to himself his twelve disciples, and gave them authority over unclean spirits, to cast them out, and to heal every disease and every sickness."},{"v":2,"t":"Now the names of the twelve apostles are these. The first, Simon, who is called Peter; Andrew, his brother; James the son of Zebedee; John, his brother;"},{"v":3,"t":"Philip; Bartholomew; Thomas; Matthew the tax collector; James the son of Alphaeus; Lebbaeus, who was also called Thaddaeus;"},{"v":4,"t":"Simon the Zealot; and Judas Iscariot, who also betrayed him."},{"v":5,"t":"Jesus sent these twelve out and commanded them, saying, “Don’t go among the Gentiles, and don’t enter into any city of the Samaritans."},{"v":6,"t":"Rather, go to the lost sheep of the house of Israel."},{"v":7,"t":"As you go, preach, saying, ‘The Kingdom of Heaven is at hand!’"},{"v":8,"t":"Heal the sick, cleanse the lepers, and cast out demons. Freely you received, so freely give."},{"v":9,"t":"Don’t take any gold, silver, or brass in your money belts."},{"v":10,"t":"Take no bag for your journey, neither two coats, nor sandals, nor staff: for the laborer is worthy of his food."},{"v":11,"t":"Into whatever city or village you enter, find out who in it is worthy, and stay there until you go on."},{"v":12,"t":"As you enter into the household, greet it."},{"v":13,"t":"If the household is worthy, let your peace come on it, but if it isn’t worthy, let your peace return to you."},{"v":14,"t":"Whoever doesn’t receive you or hear your words, as you go out of that house or that city, shake the dust off your feet."},{"v":15,"t":"Most certainly I tell you, it will be more tolerable for the land of Sodom and Gomorrah in the day of judgment than for that city."},{"v":16,"t":"“Behold, I send you out as sheep among wolves. Therefore be wise as serpents and harmless as doves."},{"v":17,"t":"But beware of men, for they will deliver you up to councils, and in their synagogues they will scourge you."},{"v":18,"t":"Yes, and you will be brought before governors and kings for my sake, for a testimony to them and to the nations."},{"v":19,"t":"But when they deliver you up, don’t be anxious how or what you will say, for it will be given you in that hour what you will say."},{"v":20,"t":"For it is not you who speak, but the Spirit of your Father who speaks in you."},{"v":21,"t":"“Brother will deliver up brother to death, and the father his child. Children will rise up against parents and cause them to be put to death."},{"v":22,"t":"You will be hated by all men for my name’s sake, but he who endures to the end will be saved."},{"v":23,"t":"But when they persecute you in this city, flee into the next, for most certainly I tell you, you will not have gone through the cities of Israel until the Son of Man has come."},{"v":24,"t":"“A disciple is not above his teacher, nor a servant above his lord."},{"v":25,"t":"It is enough for the disciple that he be like his teacher, and the servant like his lord. If they have called the master of the house Beelzebul, how much more those of his household!"},{"v":26,"t":"Therefore don’t be afraid of them, for there is nothing covered that will not be revealed, or hidden that will not be known."},{"v":27,"t":"What I tell you in the darkness, speak in the light; and what you hear whispered in the ear, proclaim on the housetops."},{"v":28,"t":"Don’t be afraid of those who kill the body, but are not able to kill the soul. Rather, fear him who is able to destroy both soul and body in Gehenna."},{"v":29,"t":"“Aren’t two sparrows sold for an assarion coin? Not one of them falls to the ground apart from your Father’s will."},{"v":30,"t":"But the very hairs of your head are all numbered."},{"v":31,"t":"Therefore don’t be afraid. You are of more value than many sparrows."},{"v":32,"t":"Everyone therefore who confesses me before men, I will also confess him before my Father who is in heaven."},{"v":33,"t":"But whoever denies me before men, I will also deny him before my Father who is in heaven."},{"v":34,"t":"“Don’t think that I came to send peace on the earth. I didn’t come to send peace, but a sword."},{"v":35,"t":"For I came to set a man at odds against his father, and a daughter against her mother, and a daughter-in-law against her mother-in-law."},{"v":36,"t":"A man’s foes will be those of his own household."},{"v":37,"t":"He who loves father or mother more than me is not worthy of me; and he who loves son or daughter more than me isn’t worthy of me."},{"v":38,"t":"He who doesn’t take his cross and follow after me isn’t worthy of me."},{"v":39,"t":"He who seeks his life will lose it; and he who loses his life for my sake will find it."},{"v":40,"t":"“He who receives you receives me, and he who receives me receives him who sent me."},{"v":41,"t":"He who receives a prophet in the name of a prophet will receive a prophet’s reward. He who receives a righteous man in the name of a righteous man will receive a righteous man’s reward."},{"v":42,"t":"Whoever gives one of these little ones just a cup of cold water to drink in the name of a disciple, most certainly I tell you, he will in no way lose his reward.”"}],"hr":[{"v":1,"t":"Dozva dvanaestoricu svojih učenika i dade im vlast nad nečistim dusima: da ih izgone i da liječe svaku bolest i svaku nemoć."},{"v":2,"t":"A ovo su imena dvanaestorice apostola: prvi Šimun, zvani Petar, i Andrija, brat njegov; i Jakov, sin Zebedejev, i Ivan brat njegov;"},{"v":3,"t":"Filip i Bartolomej; Toma i Matej carinik; Jakov Alfejev i Tadej;"},{"v":4,"t":"Šimun Kananaj i Juda Iškariotski, koji ga izda."},{"v":5,"t":"Tu dvanaestoricu posla Isus uputivši ih: “K poganima ne idite i ni u koji samarijski grad ne ulazite!"},{"v":6,"t":"Pođite radije k izgubljenim ovcama doma Izraelova!"},{"v":7,"t":"Putom propovijedajte: 'Približilo se kraljevstvo nebesko!'"},{"v":8,"t":"Bolesne liječite, mrtve uskrisujte, gubave čistite, zloduhe izgonite! Besplatno primiste, besplatno dajte!"},{"v":9,"t":"Ne stječite zlata, ni srebra, ni mjedi sebi u pojase,"},{"v":10,"t":"ni putne torbe, ni dviju haljina, ni obuće, ni štapa. Ta vrijedan je radnik hrane svoje.”"},{"v":11,"t":"“U koji god grad ili selo uđete, razvidite tko je u njemu dostojan: ondje ostanite sve dok ne odete."},{"v":12,"t":"Ulazeći u kuću, zaželite joj mir."},{"v":13,"t":"Bude li kuća dostojna, neka mir vaš siđe na nju. Ne bude li dostojna, neka se mir vaš k vama vrati."},{"v":14,"t":"Gdje vas ne prime i ne poslušaju riječi vaših, iziđite iz kuće ili grada toga i prašinu otresite sa svojih nogu."},{"v":15,"t":"Zaista, kažem vam, lakše će biti zemlji sodomskoj i gomorskoj na Dan sudnji negoli gradu tomu.”"},{"v":16,"t":"“Evo, ja vas šaljem kao ovce među vukove. Budite dakle mudri kao zmije, a bezazleni kao golubovi!"},{"v":17,"t":"Čuvajte se ljudi, jer će vas predavati vijećima i po svojim će vas sinagogama bičevati."},{"v":18,"t":"Pred upravitelje i kraljeve vodit će vas poradi mene, za svjedočanstvo njima i poganima."},{"v":19,"t":"Kad vas predadu, ne budite zabrinuti kako ili što ćete govoriti. Dat će vam se u onaj čas što ćete govoriti."},{"v":20,"t":"Ta ne govorite to vi, nego Duh Oca vašega govori u vama!”"},{"v":21,"t":"“Brat će brata predavati na smrt i otac dijete. Djeca će ustajati na roditelje i ubijati ih."},{"v":22,"t":"Svi će vas zamrziti zbog imena moga. Ali tko ustraje do svršetka, bit će spašen.”"},{"v":23,"t":"“Kad vas stanu progoniti u jednom gradu, bježite u drugi. Zaista, kažem vam, nećete obići gradova izraelskih prije nego što dođe Sin Čovječji.”"},{"v":24,"t":"“Nije učenik nad učiteljem niti sluga nad gospodarom svojim."},{"v":25,"t":"Dosta je da učenik bude kao njegov učitelj i sluga kao njegov gospodar. Ako su domaćina Beelzebulom nazvali, koliko će više njegove ukućane?”"},{"v":26,"t":"“Ne bojte ih se dakle. Ta ništa nije skriveno što se neće otkriti ni tajno što se neće doznati."},{"v":27,"t":"Što vam govorim u tami, recite na svjetlu; i što na uho čujete, propovijedajte na krovovima.”"},{"v":28,"t":"“Ne bojte se onih koji ubijaju tijelo, ali duše ne mogu ubiti. Bojte se više onoga koji može i dušu i tijelo pogubiti u paklu.”"},{"v":29,"t":"“Ne prodaju li se dva vrapca za novčić? Pa ipak ni jedan od njih ne pada na zemlju bez Oca vašega."},{"v":30,"t":"A vama su i vlasi na glavi sve izbrojene."},{"v":31,"t":"Ne bojte se dakle! Vredniji ste nego mnogo vrabaca.”"},{"v":32,"t":"“Tko god se, dakle, prizna mojim pred ljudima, priznat ću se i ja njegovim pred Ocem, koji je na nebesima."},{"v":33,"t":"A tko se odreče mene pred ljudima, odreći ću se i ja njega pred svojim Ocem, koji je na nebesima.”"},{"v":34,"t":"“Ne mislite da sam došao mir donijeti na zemlju. Ne, nisam došao donijeti mir, nego mač."},{"v":35,"t":"Ta došao sam rastaviti čovjeka od oca njegova i kćer od majke njezine i snahu od svekrve njezine;"},{"v":36,"t":"i neprijatelji će čovjeku biti ukućani njegovi."},{"v":37,"t":"“Tko ljubi oca ili majku više nego mene, nije mene dostojan. Tko ljubi sina ili kćer više nego mene, nije mene dostojan."},{"v":38,"t":"Tko ne uzme svoga križa i ne pođe za mnom, nije mene dostojan."},{"v":39,"t":"Tko nađe život svoj, izgubit će ga, a tko izgubi svoj život poradi mene, naći će ga.”"},{"v":40,"t":"“Tko vas prima, mene prima; a tko prima mene, prima onoga koji je mene poslao."},{"v":41,"t":"Tko prima proroka jer je prorok, primit će plaću proročku; tko prima pravednika jer je pravednik, primit će plaću pravedničku."},{"v":42,"t":"Tko napoji jednoga od ovih najmanjih samo čašom hladne vode zato što je moj učenik, zaista, kažem vam, neće mu propasti plaća.”"}]},"11":{"fa":[{"v":1,"t":"و چون عیسی این وصیت را با دوازده شاگرد خود به اتمام رسانید، از آنجا روانه شد تا در شهرهای ایشان تعلیم دهد و موعظه نماید."},{"v":2,"t":"و چون یحیی در زندان، اعمال مسیح راشنید، دو نفر از شاگردان خود را فرستاده،"},{"v":3,"t":"بدو گفت: «آیا آن آینده تویی یا منتظر دیگری باشیم؟»"},{"v":4,"t":"عیسی در جواب ایشان گفت: «بروید ویحیی را از آنچه شنیده و دیده‌اید، اطلاع دهید"},{"v":5,"t":"که کوران بینا می‌گردند و لنگان به رفتار می‌آیندو ابرصان طاهر و کران شنوا و مردگان زنده می‌شوند و فقیران بشارت می‌شنوند؛"},{"v":6,"t":"وخوشابحال کسی‌که در من نلغزد.»"},{"v":7,"t":"و چون ایشان می‌رفتند، عیسی با آن جماعت درباره یحیی آغاز سخن کرد که «بجهت دیدن چه چیز بیرون شدید؟ آیا نی را که از باد درجنبش است؟"},{"v":8,"t":"بلکه بجهت دیدن چه چیز بیرون شدید؟ آیا مردی را که لباس فاخر در بر دارد؟ اینک آنانی که رخت فاخر می‌پوشند در خانه های پادشاهان می‌باشند."},{"v":9,"t":"لیکن بجهت دیدن چه چیزبیرون رفتید؟ آیا نبی را؟ بلی به شما می‌گویم ازنبی افضلی را!"},{"v":10,"t":"زیرا همان است آنکه درباره اومکتوب است: “اینک من رسول خود را پیش روی تو می‌فرستم تا راه تو را پیش روی تو مهیا سازد.”"},{"v":11,"t":"هرآینه به شما می‌گویم که از اولاد زنان، بزرگتری از یحیی تعمید‌دهنده برنخاست، لیکن کوچکتر در ملکوت آسمان از وی بزرگ تر است."},{"v":12,"t":"و از ایام یحیی تعمید‌دهنده تا الان، ملکوت آسمان محبور می‌شود و جباران آن را به زورمی ربایند."},{"v":13,"t":"زیرا جمیع انبیا و تورات تا یحیی اخبار می‌نمودند."},{"v":14,"t":"و اگر خواهید قبول کنید، همان است الیاس که باید بیاید."},{"v":15,"t":"هر‌که گوش شنوا دارد بشنود."},{"v":16,"t":"لیکن این طایفه را به چه چیزتشبیه نمایم؟ اطفالی را مانند که در کوچه هانشسته، رفیقان خویش را صدا زده،"},{"v":17,"t":"می‌گویند: “برای شما نی نواختیم، رقص نکردید؛ نوحه گری کردیم، سینه نزدید.”"},{"v":18,"t":"زیرا که یحیی آمد، نه می‌خورد و نه می‌آشامید، می‌گویند دیو دارد."},{"v":19,"t":"پسر انسان آمد که می‌خورد و می‌نوشد، می‌گویند اینک مردی پرخور و میگسار و دوست باجگیران و گناهکاران است. لیکن حکمت ازفرزندان خود تصدیق کرده شده است.”» وعده آرامش درون"},{"v":20,"t":"آنگاه شروع به ملامت نمود بر آن شهرهایی که اکثر از معجزات وی در آنها ظاهرشد زیرا که توبه نکرده بودند:"},{"v":21,"t":"«وای بر تو‌ای خورزین! وای بر تو‌ای بیت صیدا! زیرا اگرمعجزاتی که در شما ظاهر گشت، در صور وصیدون ظاهر می‌شد، هرآینه مدتی در پلاس وخاکستر توبه می‌نمودند."},{"v":22,"t":"لیکن به شما می‌گویم که در روز جزا حالت صور و صیدون از شماسهلتر خواهد بود."},{"v":23,"t":"و تو‌ای کفرناحوم که تا به فلک سرافراشته‌ای، به جهنم سرنگون خواهی شد زیرا هرگاه معجزاتی که در تو پدید آمد درسدوم ظاهر می‌شد، هرآینه تا امروز باقی می‌ماند."},{"v":24,"t":"لیکن به شما می‌گویم که در روز جزاحالت زمین سدوم از تو سهل تر خواهد بود.»"},{"v":25,"t":"در آن وقت، عیسی توجه نموده، گفت: «ای پدر، مالک آسمان و زمین، تو را ستایش می‌کنم که این امور را از دانایان و خردمندان پنهان داشتی و به کودکان مکشوف فرمودی!"},{"v":26,"t":"بلی‌ای پدر، زیرا که همچنین منظور نظر تو بود."},{"v":27,"t":"پدر همه‌چیز را به من سپرده است و کسی پسر را نمی شناسد بجز پدر و نه پدر را هیچ‌کس می‌شناسد غیر از پسر و کسی‌که پسر بخواهد بدومکشوف سازد."},{"v":28,"t":"بیاید نزد من‌ای تمام زحمتکشان و گرانباران و من شما را آرامی خواهم بخشید."},{"v":29,"t":"یوغ مرا بر خود گیرید و از من تعلیم یابید زیرا که حلیم و افتاده‌دل می‌باشم و درنفوس خود آرامی خواهید یافت؛"},{"v":30,"t":"زیرا یوغ من خفیف است و بار من سبک.»"}],"en":[{"v":1,"t":"When Jesus had finished directing his twelve disciples, he departed from there to teach and preach in their cities."},{"v":2,"t":"Now when John heard in the prison the works of Christ, he sent two of his disciples"},{"v":3,"t":"and said to him, “Are you he who comes, or should we look for another?”"},{"v":4,"t":"Jesus answered them, “Go and tell John the things which you hear and see:"},{"v":5,"t":"the blind receive their sight, the lame walk, the lepers are cleansed, the deaf hear, the dead are raised up, and the poor have good news preached to them."},{"v":6,"t":"Blessed is he who finds no occasion for stumbling in me.”"},{"v":7,"t":"As these went their way, Jesus began to say to the multitudes concerning John, “What did you go out into the wilderness to see? A reed shaken by the wind?"},{"v":8,"t":"But what did you go out to see? A man in soft clothing? Behold, those who wear soft clothing are in kings’ houses."},{"v":9,"t":"But why did you go out? To see a prophet? Yes, I tell you, and much more than a prophet."},{"v":10,"t":"For this is he, of whom it is written, ‘Behold, I send my messenger before your face, who will prepare your way before you.’"},{"v":11,"t":"Most certainly I tell you, among those who are born of women there has not arisen anyone greater than John the Baptizer; yet he who is least in the Kingdom of Heaven is greater than he."},{"v":12,"t":"From the days of John the Baptizer until now, the Kingdom of Heaven suffers violence, and the violent take it by force."},{"v":13,"t":"For all the prophets and the law prophesied until John."},{"v":14,"t":"If you are willing to receive it, this is Elijah, who is to come."},{"v":15,"t":"He who has ears to hear, let him hear."},{"v":16,"t":"“But to what shall I compare this generation? It is like children sitting in the marketplaces, who call to their companions"},{"v":17,"t":"and say, ‘We played the flute for you, and you didn’t dance. We mourned for you, and you didn’t lament.’"},{"v":18,"t":"For John came neither eating nor drinking, and they say, ‘He has a demon.’"},{"v":19,"t":"The Son of Man came eating and drinking, and they say, ‘Behold, a gluttonous man and a drunkard, a friend of tax collectors and sinners!’ But wisdom is justified by her children.”"},{"v":20,"t":"Then he began to denounce the cities in which most of his mighty works had been done, because they didn’t repent."},{"v":21,"t":"“Woe to you, Chorazin! Woe to you, Bethsaida! For if the mighty works had been done in Tyre and Sidon which were done in you, they would have repented long ago in sackcloth and ashes."},{"v":22,"t":"But I tell you, it will be more tolerable for Tyre and Sidon on the day of judgment than for you."},{"v":23,"t":"You, Capernaum, who are exalted to heaven, you will go down to Hades. For if the mighty works had been done in Sodom which were done in you, it would have remained until today."},{"v":24,"t":"But I tell you that it will be more tolerable for the land of Sodom on the day of judgment, than for you.”"},{"v":25,"t":"At that time, Jesus answered, “I thank you, Father, Lord of heaven and earth, that you hid these things from the wise and understanding, and revealed them to infants."},{"v":26,"t":"Yes, Father, for so it was well-pleasing in your sight."},{"v":27,"t":"All things have been delivered to me by my Father. No one knows the Son, except the Father; neither does anyone know the Father, except the Son and he to whom the Son desires to reveal him."},{"v":28,"t":"“Come to me, all you who labor and are heavily burdened, and I will give you rest."},{"v":29,"t":"Take my yoke upon you and learn from me, for I am gentle and humble in heart; and you will find rest for your souls."},{"v":30,"t":"For my yoke is easy, and my burden is light.”"}],"hr":[{"v":1,"t":"Pošto Isus završi upućivati dvanaestoricu učenika, ode odande naučavati i propovijedati po njihovim gradovima."},{"v":2,"t":"A kad Ivan u tamnici doču za djela Kristova, posla svoje učenike"},{"v":3,"t":"da ga upitaju: “Jesi li ti Onaj koji ima doći ili drugoga da čekamo?”"},{"v":4,"t":"Isus im odgovori: “Pođite i javite Ivanu što ste čuli i vidjeli:"},{"v":5,"t":"Slijepi progledaju, hromi hode, gubavi se čiste, gluhi čuju, mrtvi ustaju, siromasima se navješćuje Evanđelje."},{"v":6,"t":"I blago onom tko se ne sablazni o mene.”"},{"v":7,"t":"Kad oni odoše, poče Isus govoriti mnoštvu o Ivanu: “Što ste izišli u pustinju gledati? Trsku koju vjetar ljulja?"},{"v":8,"t":"Ili što ste izišli vidjeti? Čovjeka u mekušasto odjevena? Eno, oni što se mekušasto nose po kraljevskim su dvorima."},{"v":9,"t":"Ili što ste izišli? Vidjeti proroka? Da, kažem vam, i više nego proroka."},{"v":10,"t":"On je onaj o kome je pisano: Evo, ja šaljem glasnika svoga pred licem tvojim da pripravi put pred tobom."},{"v":11,"t":"Zaista, kažem vam, između rođenih od žene ne usta veći od Ivana Krstitelja. A ipak, i najmanji u kraljevstvu nebeskom veći je od njega!"},{"v":12,"t":"A od dana Ivana Krstitelja do sada kraljevstvo nebesko silom se probija i siloviti ga grabe."},{"v":13,"t":"Uistinu, svi proroci i Zakon prorokovahu do Ivana."},{"v":14,"t":"Zapravo ako hoćete: on je Ilija koji ima doći.”"},{"v":15,"t":"“Tko ima uši, neka čuje.”"},{"v":16,"t":"“A komu da prispodobim ovaj naraštaj? Nalik je djeci što sjede na trgovima pa jedni drugima dovikuju:"},{"v":17,"t":"'Zasvirasmo vam i ne zaigraste, zakukasmo i ne zaplakaste.'”"},{"v":18,"t":"“Doista, dođe Ivan. Nije jeo ni pio, a govori se: 'Ðavla ima.'"},{"v":19,"t":"Dođe Sin Čovječji koji jede i pije, a govori se: 'Gle, izjelice i vinopije, prijatelja carinika i grešnika!' Ali opravda se Mudrost djelima svojim.”"},{"v":20,"t":"Tada stane prekoravati gradove u kojima se dogodilo najviše njegovih čudesa, a oni se ne obratiše:"},{"v":21,"t":"“Jao tebi, Korozaine! Jao tebi, Betsaido! Da su se u Tiru i Sidonu zbila čudesa koja su se dogodila u vama, odavna bi se već oni u kostrijeti i pepelu bili obratili."},{"v":22,"t":"Ali kažem vam: Tiru i Sidonu bit će na Dan sudnji lakše negoli vama.”"},{"v":23,"t":"“I ti, Kafarnaume! Zar ćeš se do neba uzvisiti? Do u Podzemlje ćeš se strovaliti! Doista, da su se u Sodomi zbila čudesa koja su se dogodila u tebi, ostala bi ona do danas."},{"v":24,"t":"Ali kažem vam: Zemlji će sodomskoj biti na Dan sudnji lakše nego tebi.”"},{"v":25,"t":"U ono vrijeme reče Isus: “Slavim te, Oče, Gospodaru neba i zemlje, što si ovo sakrio od mudrih i umnih, a objavio malenima."},{"v":26,"t":"Da, Oče, tako se tebi svidjelo."},{"v":27,"t":"Sve je meni predao Otac moj i nitko ne pozna Sina doli Otac niti tko pozna Oca doli Sin i onaj kome Sin hoće objaviti.”"},{"v":28,"t":"“Dođite k meni svi koji ste izmoreni i opterećeni i ja ću vas odmoriti."},{"v":29,"t":"Uzmite jaram moj na sebe, učite se od mene jer sam krotka i ponizna srca i naći ćete spokoj dušama svojim."},{"v":30,"t":"Uistinu, jaram je moj sladak i breme moje lako.”"}]},"12":{"fa":[{"v":1,"t":"در آن زمان، عیسی در روز سبت از میان کشتزارها می‌گذشت و شاگردانش چون گرسنه بودند، به چیدن و خوردن خوشه هاآغاز کردند."},{"v":2,"t":"اما فریسیان چون این را دیدند، بدوگفتند: «اینک شاگردان تو عملی می‌کنند که کردن آن در سبت جایز نیست.»"},{"v":3,"t":"ایشان را گفت: «مگرنخوانده‌اید آنچه داود و رفیقانش کردند، وقتی که گرسنه بودند؟"},{"v":4,"t":"چه طور به خانه خدا در‌آمده، نانهای تقدمه را خورد که خوردن آن بر او ورفیقانش حلال نبود بلکه بر کاهنان فقط."},{"v":5,"t":"یا درتورات نخوانده‌اید که در روزهای سبت، کهنه درهیکل سبت را حرمت نمی دارند و بی‌گناه هستند؟"},{"v":6,"t":"لیکن به شما می‌گویم که در اینجاشخصی بزرگتر از هیکل است!"},{"v":7,"t":"و اگر این معنی را درک می‌کردید که رحمت می‌خواهم نه قربانی، بی‌گناهان را مذمت نمی نمودید."},{"v":8,"t":"زیرا که پسرانسان مالک روز سبت نیز ا§ست.»"},{"v":9,"t":"و از آنجا رفته، به کنیسه ایشان درآمد،"},{"v":10,"t":"که ناگاه شخص دست خشکی حاضر بود. پس ازوی پرسیده، گفتند: «آیا در روز سبت شفا دادن جایز است یا نه؟» تا ادعایی بر او وارد آورند."},{"v":11,"t":"وی به ایشان گفت: «کیست از شما که یک گوسفند داشته باشد و هرگاه آن در روز سبت به حفره‌ای افتد، او را نخواهد گرفت و بیرون آورد؟"},{"v":12,"t":"پس چقدر انسان از گوسفند افضل است. بنابراین در سبت‌ها نیکویی‌کردن روا است.»"},{"v":13,"t":"آنگاه آن مرد را گفت: «دست خود را دراز کن!» پس دراز کرده، مانند دیگری صحیح گردید."},{"v":14,"t":"اما فریسیان بیرون رفته، بر او شورا نمودند که چطور او را هلاک کنند."},{"v":15,"t":"عیسی این را درک نموده، از آنجا روانه شدو گروهی بسیار از عقب او آمدند. پس جمیع ایشان را شفا بخشید،"},{"v":16,"t":"و ایشان را قدغن فرمودکه او را شهرت ندهند."},{"v":17,"t":"تا تمام گردد کلامی که به زبان اشعیای نبی گفته شده بود:"},{"v":18,"t":"«اینک بنده من که او را برگزیدم و حبیب من که خاطرم از وی خرسند است. روح خود را بر وی خواهم نهاد تاانصاف را بر امت‌ها اشتهار نماید."},{"v":19,"t":"نزاع و فغان نخواهد کرد و کسی آواز او را در کوچه هانخواهد شنید."},{"v":20,"t":"نی خرد شده را نخواهد شکست و فتیله نیم‌سوخته را خاموش نخواهدکرد تا آنکه انصاف را به نصرت برآورد."},{"v":21,"t":"و به نام او امت‌ها امید خواهند داشت.»"},{"v":22,"t":"آنگاه دیوانه‌ای کور و گنگ را نزد او آوردندو او را شفا داد چنانکه آن کور و گنگ، گویا و بیناشد."},{"v":23,"t":"و تمام آن گروه در حیرت افتاده، گفتند: «آیا این شخص پسر داود نیست؟»"},{"v":24,"t":"لیکن فریسیان شنیده، گفتند: «این شخص دیوها رابیرون نمی کند مگر به یاری بعلزبول، رئیس دیوها!»"},{"v":25,"t":"عیسی خیالات ایشان را درک نموده، بدیشان گفت: «هر مملکتی که بر خود منقسم گردد، ویران شود و هر شهری یا خانه‌ای که برخود منقسم گردد، برقرار نماند."},{"v":26,"t":"لهذا اگرشیطان، شیطان را بیرون کند، هرآینه بخلاف خودمنقسم گردد. پس چگونه سلطنتش پایدار ماند؟"},{"v":27,"t":"و اگر من به وساطت بعلزبول دیوها را بیرون می‌کنم، پسران شما آنها را به یاری که بیرون می‌کنند؟ از این جهت ایشان بر شما داوری خواهند کرد."},{"v":28,"t":"لیکن هرگاه من به روح خدادیوها را اخراج می‌کنم، هرآینه ملکوت خدا برشما رسیده است."},{"v":29,"t":"و چگونه کسی بتواند درخانه شخصی زورآور درآید و اسباب او را غارت کند، مگر آنکه اول آن زورآور را ببندد و پس خانه او را تاراج کند؟"},{"v":30,"t":"هر‌که با من نیست، برخلاف من است و هر‌که با من جمع نکند، پراکنده سازد."},{"v":31,"t":"از این‌رو، شما را می‌گویم هر نوع گناه و کفر از انسان آمرزیده می‌شود، لیکن کفر به روح‌القدس از انسان عفو نخواهد شد."},{"v":32,"t":"وهرکه برخلاف پسر انسان سخنی گوید، آمرزیده شود اما کسی‌که برخلاف روح‌القدس گوید، دراین عالم و در عالم آینده، هرگز آمرزیده نخواهدشد."},{"v":33,"t":"یا درخت را نیکو گردانید و میوه‌اش رانیکو، یا درخت را فاسد سازید و میوه‌اش رافاسد، زیرا که درخت از میوه‌اش شناخته می‌شود."},{"v":34,"t":"‌ای افعی‌زادگان، چگونه می‌توانیدسخن نیکو گفت و حال آنکه بد هستید زیرا که زبان از زیادتی دل سخن می‌گوید."},{"v":35,"t":"مرد نیکو ازخزانه نیکوی دل خود، چیزهای خوب برمی آورد و مرد بد از خزانه بد، چیزهای بدبیرون می‌آورد."},{"v":36,"t":"لیکن به شما می‌گویم که هرسخن باطل که مردم گویند، حساب آن را در روزداوری خواهند داد."},{"v":37,"t":"زیرا که از سخنان خودعادل شمرده خواهی شد و از سخنهای تو بر توحکم خواهد شد.»"},{"v":38,"t":"آنگاه بعضی از کاتبان و فریسیان در جواب گفتند: «ای استاد می‌خواهیم از تو آیتی ببینیم.»"},{"v":39,"t":"او در جواب ایشان گفت: «فرقه شریر و زناکارآیتی می‌طلبند و بدیشان جز آیت یونس نبی داده نخواهد شد."},{"v":40,"t":"زیرا همچنانکه یونس سه شبانه‌روز در شکم ماهی ماند، پسر انسان نیز سه شبانه‌روز در شکم زمین خواهد بود."},{"v":41,"t":"مردمان نینوا درروز داوری با این طایفه برخاسته، بر ایشان حکم خواهند کرد زیرا که به موعظه یونس توبه کردند واینک بزرگتری از یونس در اینجا است."},{"v":42,"t":"ملکه جنوب در روز داوری با این فرقه برخاسته، برایشان حکم خواهد کرد زیرا که از اقصای زمین آمد تا حکمت سلیمان را بشنود، و اینک شخصی بزرگتر از سلیمان در اینجا است."},{"v":43,"t":"و وقتی که روح پلید از آدمی بیرون آید، درطلب راحت به‌جایهای بی‌آب گردش می‌کند ونمی یابد."},{"v":44,"t":"پس می‌گوید “به خانه خود که از آن بیرون آمدم برمی گردم، “ و چون آید، آن را خالی و جاروب شده و آراسته می‌بیند."},{"v":45,"t":"آنگاه می‌رود و هفت روح دیگر بدتر از خود رابرداشته، می‌آورد و داخل گشته، ساکن آنجامی شوند و انجام آن شخص بدتر از آغازش می‌شود. همچنین به این فرقه شریر خواهد شد.»"},{"v":46,"t":"او با آن جماعت هنوز سخن می‌گفت که ناگاه مادر و برادرانش در طلب گفتگوی وی بیرون ایستاده بودند."},{"v":47,"t":"و شخصی وی را گفت: «اینک مادر تو و برادرانت بیرون ایستاده، می‌خواهند باتو سخن گویند.»"},{"v":48,"t":"در جواب قایل گفت: «کیست مادر من و برادرانم کیانند؟»"},{"v":49,"t":"و دست خود را به سوی شاگردان خود دراز کرده، گفت: «اینانند مادر من و برادرانم."},{"v":50,"t":"زیرا هر‌که اراده پدر مرا که در آسمان است به‌جا آورد، همان برادر و خواهر و مادر من است.»"}],"en":[{"v":1,"t":"At that time, Jesus went on the Sabbath day through the grain fields. His disciples were hungry and began to pluck heads of grain and to eat."},{"v":2,"t":"But the Pharisees, when they saw it, said to him, “Behold, your disciples do what is not lawful to do on the Sabbath.”"},{"v":3,"t":"But he said to them, “Haven’t you read what David did when he was hungry, and those who were with him:"},{"v":4,"t":"how he entered into God’s house and ate the show bread, which was not lawful for him to eat, nor for those who were with him, but only for the priests?"},{"v":5,"t":"Or have you not read in the law that on the Sabbath day the priests in the temple profane the Sabbath and are guiltless?"},{"v":6,"t":"But I tell you that one greater than the temple is here."},{"v":7,"t":"But if you had known what this means, ‘I desire mercy, and not sacrifice,’ you wouldn’t have condemned the guiltless."},{"v":8,"t":"For the Son of Man is Lord of the Sabbath.”"},{"v":9,"t":"He departed from there and went into their synagogue."},{"v":10,"t":"And behold, there was a man with a withered hand. They asked him, “Is it lawful to heal on the Sabbath day?” so that they might accuse him."},{"v":11,"t":"He said to them, “What man is there among you who has one sheep, and if this one falls into a pit on the Sabbath day, won’t he grab on to it and lift it out?"},{"v":12,"t":"Of how much more value then is a man than a sheep! Therefore it is lawful to do good on the Sabbath day.”"},{"v":13,"t":"Then he told the man, “Stretch out your hand.” He stretched it out; and it was restored whole, just like the other."},{"v":14,"t":"But the Pharisees went out and conspired against him, how they might destroy him."},{"v":15,"t":"Jesus, perceiving that, withdrew from there. Great multitudes followed him; and he healed them all,"},{"v":16,"t":"and commanded them that they should not make him known,"},{"v":17,"t":"that it might be fulfilled which was spoken through Isaiah the prophet, saying,"},{"v":18,"t":"“Behold, my servant whom I have chosen, my beloved in whom my soul is well pleased. I will put my Spirit on him. He will proclaim justice to the nations."},{"v":19,"t":"He will not strive, nor shout, neither will anyone hear his voice in the streets."},{"v":20,"t":"He won’t break a bruised reed. He won’t quench a smoking flax, until he leads justice to victory."},{"v":21,"t":"In his name, the nations will hope.”"},{"v":22,"t":"Then one possessed by a demon, blind and mute, was brought to him; and he healed him, so that the blind and mute man both spoke and saw."},{"v":23,"t":"All the multitudes were amazed, and said, “Can this be the son of David?”"},{"v":24,"t":"But when the Pharisees heard it, they said, “This man does not cast out demons except by Beelzebul, the prince of the demons.”"},{"v":25,"t":"Knowing their thoughts, Jesus said to them, “Every kingdom divided against itself is brought to desolation, and every city or house divided against itself will not stand."},{"v":26,"t":"If Satan casts out Satan, he is divided against himself. How then will his kingdom stand?"},{"v":27,"t":"If I by Beelzebul cast out demons, by whom do your children cast them out? Therefore they will be your judges."},{"v":28,"t":"But if I by the Spirit of God cast out demons, then God’s Kingdom has come upon you."},{"v":29,"t":"Or how can one enter into the house of the strong man and plunder his goods, unless he first bind the strong man? Then he will plunder his house."},{"v":30,"t":"“He who is not with me is against me, and he who doesn’t gather with me, scatters."},{"v":31,"t":"Therefore I tell you, every sin and blasphemy will be forgiven men, but the blasphemy against the Spirit will not be forgiven men."},{"v":32,"t":"Whoever speaks a word against the Son of Man, it will be forgiven him; but whoever speaks against the Holy Spirit, it will not be forgiven him, either in this age, or in that which is to come."},{"v":33,"t":"“Either make the tree good and its fruit good, or make the tree corrupt and its fruit corrupt; for the tree is known by its fruit."},{"v":34,"t":"You offspring of vipers, how can you, being evil, speak good things? For out of the abundance of the heart, the mouth speaks."},{"v":35,"t":"The good man out of his good treasure brings out good things, and the evil man out of his evil treasure brings out evil things."},{"v":36,"t":"I tell you that every idle word that men speak, they will give account of it in the day of judgment."},{"v":37,"t":"For by your words you will be justified, and by your words you will be condemned.”"},{"v":38,"t":"Then certain of the scribes and Pharisees answered, “Teacher, we want to see a sign from you.”"},{"v":39,"t":"But he answered them, “An evil and adulterous generation seeks after a sign, but no sign will be given to it but the sign of Jonah the prophet."},{"v":40,"t":"For as Jonah was three days and three nights in the belly of the huge fish, so will the Son of Man be three days and three nights in the heart of the earth."},{"v":41,"t":"The men of Nineveh will stand up in the judgment with this generation and will condemn it, for they repented at the preaching of Jonah; and behold, someone greater than Jonah is here."},{"v":42,"t":"The Queen of the South will rise up in the judgment with this generation and will condemn it, for she came from the ends of the earth to hear the wisdom of Solomon; and behold, someone greater than Solomon is here."},{"v":43,"t":"“When an unclean spirit has gone out of a man, he passes through waterless places seeking rest, and doesn’t find it."},{"v":44,"t":"Then he says, ‘I will return into my house from which I came;’ and when he has come back, he finds it empty, swept, and put in order."},{"v":45,"t":"Then he goes and takes with himself seven other spirits more evil than he is, and they enter in and dwell there. The last state of that man becomes worse than the first. Even so will it be also to this evil generation.”"},{"v":46,"t":"While he was yet speaking to the multitudes, behold, his mother and his brothers stood outside, seeking to speak to him."},{"v":47,"t":"One said to him, “Behold, your mother and your brothers stand outside, seeking to speak to you.”"},{"v":48,"t":"But he answered him who spoke to him, “Who is my mother? Who are my brothers?”"},{"v":49,"t":"He stretched out his hand toward his disciples, and said, “Behold, my mother and my brothers!"},{"v":50,"t":"For whoever does the will of my Father who is in heaven, he is my brother, and sister, and mother.”"}],"hr":[{"v":1,"t":"U ono vrijeme prolazio je Isus subotom kroz usjeve. Učenici su njegovi ogladnjeli te počeli trgati klasje i jesti."},{"v":2,"t":"Vidjevši to, farizeji mu rekoše: “Gle, učenici tvoji čine što nije dopušteno činiti subotom.”"},{"v":3,"t":"On im reče: “Niste li čitali što učini David kad ogladnje on i njegovi pratioci?"},{"v":4,"t":"Kako uđe u Dom Božji te pojedoše prinesene kruhove, a to ne bijaše slobodno jesti ni njemu ni njegovim pratiocima, nego samo svećenicima?"},{"v":5,"t":"Ili zar niste čitali u Zakonu da subotom svećenici u Hramu krše subotu, a bez krivnje su?"},{"v":6,"t":"A velim vam: veće od Hrama jest ovdje!"},{"v":7,"t":"I kad biste razumjeli što ono znači: Milosrđe mi je milo, a ne žrtva, ne biste osudili ove nekrive."},{"v":8,"t":"Ta Sin Čovječji gospodar je subote!”"},{"v":9,"t":"Otišavši odande, dođe u njihovu sinagogu,"},{"v":10,"t":"kad gle čovjeka s usahlom rukom. A oni upitaše Isusa da bi ga mogli optužiti: “Je li dopušteno subotom liječiti?”"},{"v":11,"t":"On im reče: “Tko to od vas jedinu ovcu koju ima ne bi subotom prihvatio i izvadio kad bi mu upala u jamu?"},{"v":12,"t":"A koliko je čovjek vredniji od ovce! Tako, slobodno je subotom činiti dobro!”"},{"v":13,"t":"Tada reče čovjeku: “Ispruži ruku!” On je ispruži, i - ruka mu zdrava kao i druga!"},{"v":14,"t":"A farizeji iziđoše i održaše vijećanje protiv njega, kako da ga pogube."},{"v":15,"t":"Kad Isus to dozna, ukloni se odande. Za njim je išlo mnoštvo. On ih sve ozdravi"},{"v":16,"t":"i poprijeti im da ga ne prokazuju -"},{"v":17,"t":"da se ispuni što je rečeno po Izaiji proroku:"},{"v":18,"t":"Evo Sluge mojega, koga sebi izabrah: mog ljubimca, miljenika duše moje! Stavit ću Duha svoga na njega: naviještat će pravo narodima;"},{"v":19,"t":"preti se neće, neće bučiti, glas mu se neće čuti po trgovima;"},{"v":20,"t":"trske stučene prelomiti neće, stijenja što tek tinja neće ugasiti - sve dok do pobjede ne izvede pravo."},{"v":21,"t":"Ime njegovo nada je narodima!"},{"v":22,"t":"Tada mu donesoše opsjednuta, slijepa i nijema. I ozdravi ga te njemak progovori i progleda."},{"v":23,"t":"I sve ono mnoštvo zapanjeno govoraše: “Da ovo nije Sin Davidov?”"},{"v":24,"t":"A farizeji čuvši to rekoše: “Ne može ovaj izgoniti đavle osim po Beelzebulu, poglavici đavolskom.”"},{"v":25,"t":"A on, znajući njihove misli, reče im: “Svako kraljevstvo u sebi razdijeljeno opustjet će i svaki grad ili kuća u sebi razdijeljena neće opstati."},{"v":26,"t":"Ako Sotona Sotonu izgoni, u sebi je razdijeljen. Kako će dakle opstati kraljevstvo njegovo?"},{"v":27,"t":"I ako ja po Beelzebulu izgonim đavle, po kome ih sinovi vaši izgone? Zato će vam oni biti suci."},{"v":28,"t":"Ali ako ja po Duhu Božjem izgonim đavle, zbilja je došlo k vama kraljevstvo Božje.”"},{"v":29,"t":"“Ili kako bi tko mogao ući u kuću jakoga i oplijeniti mu pokućstvo ako prije ne sveže jakoga? Tada će mu kuću oplijeniti.”"},{"v":30,"t":"“Tko nije sa mnom, protiv mene je, i tko ne sabire sa mnom, rasipa.”"},{"v":31,"t":"“Zato kažem vam: svaki će se grijeh i bogohulstvo oprostiti ljudima, ali rekne li tko bogohulstvo protiv Duha, neće se oprostiti."},{"v":32,"t":"I rekne li tko riječ protiv Sina Čovječjega, oprostit će mu se. Ali tko rekne protiv Duha Svetoga, neće mu se oprostiti ni na ovom svijetu ni u budućem.”"},{"v":33,"t":"“Ili uzmite: dobro stablo i plod mu je dobar. Ili uzmite: trulo stablo i plod mu je truo. Ta po plodu se stablo poznaje."},{"v":34,"t":"Leglo gujinje! Kako možete govoriti dobro kad ste opaki. Ta iz obilja srca usta govore!"},{"v":35,"t":"Dobar čovjek iz riznice dobre vadi dobro, a zao čovjek iz riznice zle vadi zlo."},{"v":36,"t":"A kažem vam: za svaku bezrazložnu riječ koju ljudi reknu dat će račun na Dan sudnji."},{"v":37,"t":"Doista, tvoje će te riječi opravdati i tvoje će te riječi osuditi.”"},{"v":38,"t":"Jednom zapodjenuše s njime razgovor neki pismoznanci i farizeji: “Učitelju, htjeli bismo od tebe vidjeti znak.”"},{"v":39,"t":"A on im odgovori: “Naraštaj opak i preljubnički znak traži, ali mu se znak neće dati doli znak Jone proroka."},{"v":40,"t":"Doista, kao što Jona bijaše u utrobi kitovoj tri dana i tri noći, tako će i Sin Čovječji biti u srcu zemlje tri dana i tri noći."},{"v":41,"t":"Ninivljani će ustati na Sudu zajedno s ovim naraštajem i osuditi ga jer se oni na propovijed Joninu obratiše, a evo, ovdje je i više od Jone!"},{"v":42,"t":"Kraljica će Juga ustati na Sudu zajedno s ovim naraštajem i osuditi ga jer je s krajeva zemlje došla čuti mudrost Salomonovu, a evo, ovdje je i više od Salomona!”"},{"v":43,"t":"“A kad nečisti duh iziđe iz čovjeka, luta bezvodnim mjestima tražeći spokoja, ali ne nalazi!"},{"v":44,"t":"Tada rekne: 'Vratit ću se u kuću odakle iziđoh.' I došavši, nađe je praznu, pometenu i uređenu."},{"v":45,"t":"Tada ode i uzme sa sobom sedam drugih duhova, gorih od sebe, te uđu i nastane se ondje. Na kraju bude s onim čovjekom gore nego na početku. Tako će biti i s ovim opakim naraštajem.”"},{"v":46,"t":"Dok on još govoraše mnoštvu, eto majke i braće njegove. Stajahu vani tražeći da s njime govore."},{"v":47,"t":"Reče mu netko: “Evo majke tvoje i braće tvoje, vani stoje i traže da s tobom govore.”"},{"v":48,"t":"Tomu koji mu to javi on odgovori: “Tko je majka moja, tko li braća moja?”"},{"v":49,"t":"I pruži ruku prema učenicima: “Evo, reče, majke moje i braće moje!"},{"v":50,"t":"Doista, tko god vrši volju Oca mojega, koji je na nebesima, taj mi je brat i sestra i majka.”"}]},"13":{"fa":[{"v":1,"t":"و در همان روز، عیسی از خانه بیرون آمده، به کناره دریا نشست"},{"v":2,"t":"و گروهی بسیار بر وی جمع آمدند، بقسمی که او به کشتی سوار شده، قرار گرفت و تمامی آن گروه بر ساحل ایستادند؛"},{"v":3,"t":"و معانی بسیار به مثلها برای ایشان گفت: «وقتی برزگری بجهت پاشیدن تخم بیرون شد."},{"v":4,"t":"و چون تخم می‌پاشید، قدری در راه افتاد ومرغان آمده، آن را خوردند."},{"v":5,"t":"و بعضی برسنگلاخ جایی که خاک زیاد نداشت افتاده، بزودی سبز شد، چونکه زمین عمق نداشت،"},{"v":6,"t":"وچون آفتاب برآمد بسوخت و چون ریشه نداشت خشکید."},{"v":7,"t":"و بعضی در میان خارها ریخته شد وخارها نمو کرده، آن را خفه نمود."},{"v":8,"t":"و برخی درزمین نیکو کاشته شده، بار آورد، بعضی صد وبعضی شصت و بعضی سی."},{"v":9,"t":"هر‌که گوش شنوادارد بشنود.»"},{"v":10,"t":"آنگاه شاگردانش آمده، به وی گفتند: «ازچه جهت با اینها به مثلها سخن می‌رانی؟»"},{"v":11,"t":"درجواب ایشان گفت: «دانستن اسرار ملکوت آسمان به شما عطا شده است، لیکن بدیشان عطانشده،"},{"v":12,"t":"زیرا هر‌که دارد بدو داده شود و افزونی یابد. اما کسی‌که ندارد آنچه دارد هم از او گرفته خواهد شد."},{"v":13,"t":"از این جهت با اینها به مثلها سخن می گویم که نگرانند و نمی بینند و شنوا هستند ونمی شنوند و نمی فهمند."},{"v":14,"t":"و در حق ایشان نبوت اشعیا تمام می‌شود که می‌گوید: “به سمع خواهید شنید و نخواهید فهمید و نظر کرده، خواهید نگریست و نخواهید دید."},{"v":15,"t":"زیرا قلب این قوم سنگین شده و به گوشها به سنگینی شنیده‌اند و چشمان خود را بر هم نهاده‌اند، مبادابه چشمها ببینند و به گوشها بشنوند و به دلهابفهمند و بازگشت کنند و من ایشان را شفا دهم.”"},{"v":16,"t":"لیکن خوشابه‌حال چشمان شما زیرا که می‌بینند و گوشهای شما زیرا که می‌شنوند"},{"v":17,"t":"زیرا هرآینه به شما می‌گویم بسا انبیا وعادلان خواستند که آنچه شما می‌بینید، ببینندو ندیدند و آنچه می‌شنوید، بشنوند ونشنیدند."},{"v":18,"t":"پس شما مثل برزگر را بشنوید."},{"v":19,"t":"کسی‌که کلمه ملکوت را شنیده، آن را نفهمید، شریرمی آید و آنچه در دل او کاشته شده است می‌رباید، همان است آنکه در راه کاشته شده است."},{"v":20,"t":"و آنکه بر سنگلاخ ریخته شده، اوست که کلام را شنیده، فی الفور به خشنودی قبول می‌کند،"},{"v":21,"t":"و لکن ریشه‌ای در خود ندارد، بلکه فانی است و هرگاه سختی یا صدمه‌ای به‌سبب کلام بر او وارد آید، در ساعت لغزش می‌خورد."},{"v":22,"t":"و آنکه در میان خارها ریخته شد، آن است که کلام را بشنود واندیشه این جهان و غرور دولت، کلام را خفه کند و بی‌ثمر گردد."},{"v":23,"t":"و آنکه درزمین نیکو کاشته شد، آن است که کلام را شنیده، آن را می‌فهمد و بارآور شده، بعضی صد و بعضی شصت و بعضی سی ثمر می‌آورد.»"},{"v":24,"t":"و مثلی دیگر بجهت ایشان آورده، گفت: «ملکوت آسمان مردی را ماند که تخم نیکو درزمین خود کاشت:"},{"v":25,"t":"و چون مردم در خواب بودند دشمنش آمده، در میان گندم، کرکاس ریخته، برفت."},{"v":26,"t":"و وقتی که گندم رویید و خوشه برآورد، کرکاس نیز ظاهر شد."},{"v":27,"t":"پس نوکران صاحب‌خانه آمده، به وی عرض کردند: “ای آقامگر تخم نیکو در زمین خویش نکاشته‌ای؟ پس ازکجا کرکاس بهم رسانید؟”"},{"v":28,"t":"ایشان را فرمود: “این کار دشمن است.” عرض کردند: “آیامی خواهی برویم آنها را جمع کنیم؟”"},{"v":29,"t":"فرمود: “نی، مبادا وقت جمع کردن کرکاس، گندم را باآنها برکنید."},{"v":30,"t":"بگذارید که هر دو تا وقت حصاد باهم نمو کنند و در موسم حصاد، دروگران راخواهم گفت که اول کرکاسها را جمع کرده، آنهارا برای سوختن بافه‌ها ببندید اما گندم را در انبارمن ذخیره کنید.”» مثل دانه خردل"},{"v":31,"t":"بار دیگر مثلی برای ایشان زده، گفت: «ملکوت آسمان مثل دانه خردلی است که شخصی گرفته، در مزرعه خویش کاشت."},{"v":32,"t":"وهرچند از سایر دانه‌ها کوچکتر است، ولی چون نمو کند بزرگترین بقول است و درختی می‌شودچنانکه مرغان هوا آمده در شاخه هایش آشیانه می گیرند.»"},{"v":33,"t":"و مثلی دیگر برای ایشان گفت که ملکوت آسمان خمیرمایه‌ای را ماند که زنی آن را گرفته، در سه کیل خمیر پنهان کرد تا تمام، مخمر گشت."},{"v":34,"t":"همه این معانی را عیسی با آن گروه به مثلهاگفت و بدون مثل بدیشان هیچ نگفت،"},{"v":35,"t":"تا تمام گردد کلامی که به زبان نبی گفته شد: «دهان خودرا به مثلها باز می‌کنم و به چیزهای مخفی شده ازبنای عالم تنطق خواهم کرد.»"},{"v":36,"t":"آنگاه عیسی آن گروه را مرخص کرده، داخل خانه گشت و شاگردانش نزد وی آمده، گفتند: «مثل کرکاس مزرعه را بجهت ما شرح فرما.»"},{"v":37,"t":"در جواب ایشان گفت: «آنکه بذر نیکومی کارد پسر انسان است،"},{"v":38,"t":"و مزرعه، این جهان است و تخم نیکو ابنای ملکوت و کرکاسها، پسران شریرند."},{"v":39,"t":"و دشمنی که آنها را کاشت، ابلیس است و موسم حصاد، عاقبت این عالم ودروندگان، فرشتگانند."},{"v":40,"t":"پس همچنان‌که کرکاسها را جمع کرده، در آتش می‌سوزانند، همانطور در عاقبت این عالم خواهد شد،"},{"v":41,"t":"که پسر انسان ملائکه خود را فرستاده، همه لغزش دهندگان و بدکاران را جمع خواهند کرد،"},{"v":42,"t":"و ایشان را به تنور آتش خواهند انداخت، جایی که گریه و فشار دندان بود."},{"v":43,"t":"آنگاه عادلان در ملکوت پدر خود مثل آفتاب، درخشان خواهند شد. هر‌که گوش شنوا دارد بشنود."},{"v":44,"t":"«و ملکوت آسمان گنجی را ماند، مخفی شده در زمین که شخصی آن را یافته، پنهان نمودو از خوشی آن رفته، آنچه داشت فروخت و آن زمین را خرید."},{"v":45,"t":"«باز ملکوت آسمان تاجری را ماند که جویای مرواریدهای خوب باشد،"},{"v":46,"t":"و چون یک مروارید گرانبها یافت، رفت و مایملک خود رافروخته، آن را خرید."},{"v":47,"t":"«ایض ملکوت آسمان مثل دامی است که به دریا افکنده شود و از هر جنسی به آن درآید،"},{"v":48,"t":"وچون پر شود، به کناره‌اش کشند و نشسته، خوبهارا در ظروف جمع کنند و بدها را دور اندازند."},{"v":49,"t":"بدینطور در آخر این عالم خواهد شد. فرشتگان بیرون آمده، طالحین را از میان صالحین جدا کرده،"},{"v":50,"t":"ایشان را در تنور آتش خواهندانداخت، جایی که گریه و فشار دندان می‌باشد.»"},{"v":51,"t":"عیسی ایشان را گفت: «آیا همه این امور رافهمیده‌اید؟» گفتندش: «بلی خداوندا.»"},{"v":52,"t":"به ایشان گفت: «بنابراین، هر کاتبی که در ملکوت آسمان تعلیم یافته است، مثل صاحب‌خانه‌ای است که از خزانه خویش چیزهای نو و کهنه بیرون می‌آورد.»"},{"v":53,"t":"و چون عیسی این مثلها را به اتمام رسانید، از آن موضع روانه شد."},{"v":54,"t":"و چون به وطن خویش آمد، ایشان را در کنیسه ایشان تعلیم داد، بقسمی که متعجب شده، گفتند: «از کجا این شخص چنین حکمت و معجزات را بهم رسانید؟"},{"v":55,"t":"آیا این پسر نجار نمی باشد؟ و آیا مادرش مریم نامی نیست؟ و برادرانش یعقوب و یوسف و شمعون ویهودا؟"},{"v":56,"t":"و همه خواهرانش نزد ما نمی باشند؟ پس این همه را از کجا بهم رسانید؟»"},{"v":57,"t":"و درباره او لغزش خوردند. لیکن عیسی بدیشان گفت: «نبی بی‌حرمت نباشد مگر در وطن و خانه خویش.»"},{"v":58,"t":"و به‌سبب بی‌ایمانی‌ایشان معجزه بسیار در آنجا ظاهر نساخت."}],"en":[{"v":1,"t":"On that day Jesus went out of the house and sat by the seaside."},{"v":2,"t":"Great multitudes gathered to him, so that he entered into a boat and sat; and all the multitude stood on the beach."},{"v":3,"t":"He spoke to them many things in parables, saying, “Behold, a farmer went out to sow."},{"v":4,"t":"As he sowed, some seeds fell by the roadside, and the birds came and devoured them."},{"v":5,"t":"Others fell on rocky ground, where they didn’t have much soil, and immediately they sprang up, because they had no depth of earth."},{"v":6,"t":"When the sun had risen, they were scorched. Because they had no root, they withered away."},{"v":7,"t":"Others fell among thorns. The thorns grew up and choked them."},{"v":8,"t":"Others fell on good soil and yielded fruit: some one hundred times as much, some sixty, and some thirty."},{"v":9,"t":"He who has ears to hear, let him hear.”"},{"v":10,"t":"The disciples came, and said to him, “Why do you speak to them in parables?”"},{"v":11,"t":"He answered them, “To you it is given to know the mysteries of the Kingdom of Heaven, but it is not given to them."},{"v":12,"t":"For whoever has, to him will be given, and he will have abundance; but whoever doesn’t have, from him will be taken away even that which he has."},{"v":13,"t":"Therefore I speak to them in parables, because seeing they don’t see, and hearing, they don’t hear, neither do they understand."},{"v":14,"t":"In them the prophecy of Isaiah is fulfilled, which says, ‘By hearing you will hear, and will in no way understand; Seeing you will see, and will in no way perceive;"},{"v":15,"t":"for this people’s heart has grown callous, their ears are dull of hearing, and they have closed their eyes; or else perhaps they might perceive with their eyes, hear with their ears, understand with their heart, and would turn again, and I would heal them.’"},{"v":16,"t":"“But blessed are your eyes, for they see; and your ears, for they hear."},{"v":17,"t":"For most certainly I tell you that many prophets and righteous men desired to see the things which you see, and didn’t see them; and to hear the things which you hear, and didn’t hear them."},{"v":18,"t":"“Hear, then, the parable of the farmer."},{"v":19,"t":"When anyone hears the word of the Kingdom and doesn’t understand it, the evil one comes and snatches away that which has been sown in his heart. This is what was sown by the roadside."},{"v":20,"t":"What was sown on the rocky places, this is he who hears the word and immediately with joy receives it;"},{"v":21,"t":"yet he has no root in himself, but endures for a while. When oppression or persecution arises because of the word, immediately he stumbles."},{"v":22,"t":"What was sown among the thorns, this is he who hears the word, but the cares of this age and the deceitfulness of riches choke the word, and he becomes unfruitful."},{"v":23,"t":"What was sown on the good ground, this is he who hears the word and understands it, who most certainly bears fruit and produces, some one hundred times as much, some sixty, and some thirty.”"},{"v":24,"t":"He set another parable before them, saying, “The Kingdom of Heaven is like a man who sowed good seed in his field,"},{"v":25,"t":"but while people slept, his enemy came and sowed darnel weeds also among the wheat, and went away."},{"v":26,"t":"But when the blade sprang up and produced grain, then the darnel weeds appeared also."},{"v":27,"t":"The servants of the householder came and said to him, ‘Sir, didn’t you sow good seed in your field? Where did these darnel weeds come from?’"},{"v":28,"t":"“He said to them, ‘An enemy has done this.’ “The servants asked him, ‘Do you want us to go and gather them up?’"},{"v":29,"t":"“But he said, ‘No, lest perhaps while you gather up the darnel weeds, you root up the wheat with them."},{"v":30,"t":"Let both grow together until the harvest, and in the harvest time I will tell the reapers, “First, gather up the darnel weeds, and bind them in bundles to burn them; but gather the wheat into my barn.”’”"},{"v":31,"t":"He set another parable before them, saying, “The Kingdom of Heaven is like a grain of mustard seed which a man took, and sowed in his field,"},{"v":32,"t":"which indeed is smaller than all seeds. But when it is grown, it is greater than the herbs and becomes a tree, so that the birds of the air come and lodge in its branches.”"},{"v":33,"t":"He spoke another parable to them. “The Kingdom of Heaven is like yeast which a woman took and hid in three measures of meal, until it was all leavened.”"},{"v":34,"t":"Jesus spoke all these things in parables to the multitudes; and without a parable, he didn’t speak to them,"},{"v":35,"t":"that it might be fulfilled which was spoken through the prophet, saying, “I will open my mouth in parables; I will utter things hidden from the foundation of the world.”"},{"v":36,"t":"Then Jesus sent the multitudes away, and went into the house. His disciples came to him, saying, “Explain to us the parable of the darnel weeds of the field.”"},{"v":37,"t":"He answered them, “He who sows the good seed is the Son of Man,"},{"v":38,"t":"the field is the world, the good seeds are the children of the Kingdom, and the darnel weeds are the children of the evil one."},{"v":39,"t":"The enemy who sowed them is the devil. The harvest is the end of the age, and the reapers are angels."},{"v":40,"t":"As therefore the darnel weeds are gathered up and burned with fire; so will it be at the end of this age."},{"v":41,"t":"The Son of Man will send out his angels, and they will gather out of his Kingdom all things that cause stumbling and those who do iniquity,"},{"v":42,"t":"and will cast them into the furnace of fire. There will be weeping and gnashing of teeth."},{"v":43,"t":"Then the righteous will shine like the sun in the Kingdom of their Father. He who has ears to hear, let him hear."},{"v":44,"t":"“Again, the Kingdom of Heaven is like treasure hidden in the field, which a man found and hid. In his joy, he goes and sells all that he has and buys that field."},{"v":45,"t":"“Again, the Kingdom of Heaven is like a man who is a merchant seeking fine pearls,"},{"v":46,"t":"who having found one pearl of great price, he went and sold all that he had and bought it."},{"v":47,"t":"“Again, the Kingdom of Heaven is like a dragnet that was cast into the sea and gathered some fish of every kind,"},{"v":48,"t":"which, when it was filled, fishermen drew up on the beach. They sat down and gathered the good into containers, but the bad they threw away."},{"v":49,"t":"So it will be in the end of the world. The angels will come and separate the wicked from among the righteous,"},{"v":50,"t":"and will cast them into the furnace of fire. There will be weeping and gnashing of teeth.”"},{"v":51,"t":"Jesus said to them, “Have you understood all these things?” They answered him, “Yes, Lord.”"},{"v":52,"t":"He said to them, “Therefore every scribe who has been made a disciple in the Kingdom of Heaven is like a man who is a householder, who brings out of his treasure new and old things.”"},{"v":53,"t":"When Jesus had finished these parables, he departed from there."},{"v":54,"t":"Coming into his own country, he taught them in their synagogue, so that they were astonished and said, “Where did this man get this wisdom and these mighty works?"},{"v":55,"t":"Isn’t this the carpenter’s son? Isn’t his mother called Mary, and his brothers James, Joses, Simon, and Judas?"},{"v":56,"t":"Aren’t all of his sisters with us? Where then did this man get all of these things?”"},{"v":57,"t":"They were offended by him. But Jesus said to them, “A prophet is not without honor, except in his own country and in his own house.”"},{"v":58,"t":"He didn’t do many mighty works there because of their unbelief."}],"hr":[{"v":1,"t":"Onoga dana Isus iziđe iz kuće i sjede uz more."},{"v":2,"t":"I nagrnu k njemu silan svijet te je morao ući u lađu: sjede, a sve ono mnoštvo stajaše na obali."},{"v":3,"t":"I zborio im je mnogo u prispodobama: “Gle, iziđe sijač sijati."},{"v":4,"t":"I dok je sijao, nešto zrnja pade uz put, dođoše ptice i pozobaše ga."},{"v":5,"t":"Nešto opet pade na kamenito tlo, gdje nemaše dosta zemlje, i odmah izniknu jer nemaše duboke zemlje."},{"v":6,"t":"A kad sunce ogranu, izgorje i jer nemaše korijena, osuši se."},{"v":7,"t":"Nešto opet pade u trnje, trnje uzraste i uguši ga."},{"v":8,"t":"Nešto napokon pade na dobru zemlju i davaše plod: jedno stostruk, drugo šezdesetostruk, treće tridesetostruk.”"},{"v":9,"t":"“Tko ima uši, neka čuje!”"},{"v":10,"t":"I pristupe učenici pa ga zapitaju: “Zašto im zboriš u prispodobama?”"},{"v":11,"t":"On im odgovori: “Zato što je vama dano znati otajstva kraljevstva nebeskoga, a njima nije dano."},{"v":12,"t":"Doista, onomu tko ima dat će se i obilovat će, a onomu tko nema oduzet će se i ono što ima."},{"v":13,"t":"U prispodobama im zborim zato što gledajući ne vide i slušajući ne čuju i ne razumiju.”"},{"v":14,"t":"“Tako se ispunja na njima proroštvo Izaijino koje govori: Slušat ćete, slušati - i nećete razumjeti; gledat ćete, gledati - i nećete vidjeti!"},{"v":15,"t":"Jer usalilo se srce naroda ovoga: uši začepiše, oči zatvoriše da očima ne vide, ušima ne čuju, srcem ne razumiju te se ne obrate pa ih izliječim."},{"v":16,"t":"A blago vašim očima što vide, i ušima što slušaju."},{"v":17,"t":"Zaista, kažem vam, mnogi su proroci i pravednici željeli vidjeti što vi gledate, ali nisu vidjeli; i čuti što vi slušate, ali nisu čuli.”"},{"v":18,"t":"“Vi, dakle, poslušajte prispodobu o sijaču."},{"v":19,"t":"Svakomu koji sluša Riječ o Kraljevstvu, a ne razumije, dolazi Zli te otima što mu je u srcu posijano. To je onaj uz put zasijan."},{"v":20,"t":"A zasijani na tlo kamenito - to je onaj koji čuje Riječ i odmah je s radošću prima,"},{"v":21,"t":"ali nema u sebi korijena, nego je nestalan: kad zbog Riječi nastane nevolja ili progonstvo, odmah se pokoleba."},{"v":22,"t":"Zasijani u trnje - to je onaj koji sluša Riječ, ali briga vremenita i zavodljivost bogatstva uguše Riječ, te ona ostane bez ploda."},{"v":23,"t":"Zasijani na dobru zemlju - to je onaj koji Riječ sluša i razumije, pa onda, dakako, urodi i daje: jedan stostruko, jedan šezdesetostruko, a jedan tridesetostruko.”"},{"v":24,"t":"Drugu im prispodobu iznese: “Kraljevstvo je nebesko kao kad čovjek posije dobro sjeme na svojoj njivi."},{"v":25,"t":"Dok su njegovi ljudi spavali, dođe njegov neprijatelj, posije posred žita kukolj i ode."},{"v":26,"t":"Kad usjev uzraste i isklasa, tada se pokaza i kukolj."},{"v":27,"t":"Sluge pristupe domaćinu pa mu reknu: 'Gospodaru, nisi li ti dobro sjeme posijao na svojoj njivi? Odakle onda kukolj?'"},{"v":28,"t":"On im odgovori: 'Neprijatelj čovjek to učini.' Nato mu sluge kažu: 'Hoćeš li, dakle, da odemo pa da ga pokupimo?'"},{"v":29,"t":"A on reče: 'Ne! Da ne biste sabirući kukolj iščupali zajedno s njim i pšenicu."},{"v":30,"t":"Pustite nek oboje raste do žetve. U vrijeme žetve reći ću žeteocima: Pokupite najprije kukolj i svežite ga u snopove da se spali, a žito skupite u moju žitnicu.'”"},{"v":31,"t":"I drugu im prispodobu iznese: “Kraljevstvo je nebesko kao kad čovjek uze gorušičino zrno i posija ga na svojoj njivi."},{"v":32,"t":"Ono je doduše najmanje od svega sjemenja, ali kad uzraste, veće je od svega povrća. Razvije se u stablo te dolaze ptice nebeske i gnijezde mu se po granama.”"},{"v":33,"t":"I drugu im kaza prispodobu: “Kraljevstvo je nebesko kao kad žena uze kvasac i zamijesi ga u tri mjere brašna dok sve ne uskisne.”"},{"v":34,"t":"Sve je to Isus mnoštvu zborio u prispodobama. I ništa im nije zborio bez prispodoba -"},{"v":35,"t":"da se ispuni što je rečeno po proroku: Otvorit ću u prispodobama usta svoja, iznijet ću što je sakriveno od postanka svijeta."},{"v":36,"t":"Tada otpusti mnoštvo i uđe u kuću. Pristupe mu učenici govoreći: “Razjasni nam prispodobu o kukolju na njivi.”"},{"v":37,"t":"On odgovori: “Sijač dobroga sjemena jest Sin Čovječji."},{"v":38,"t":"Njiva je svijet. Dobro sjeme sinovi su Kraljevstva, a kukolj sinovi Zloga."},{"v":39,"t":"Neprijatelj koji ga posija jest đavao. Žetva je svršetak svijeta, a žeteoci anđeli."},{"v":40,"t":"Kao što se kukolj sabire i ognjem sažiže, tako će biti na svršetku svijeta."},{"v":41,"t":"Sin će Čovječji poslati svoje anđele da pokupe iz njegova kraljevstva sve zavodnike i bezakonike"},{"v":42,"t":"i bace ih u peć ognjenu, gdje će biti plač i škrgut zubi."},{"v":43,"t":"Tada će pravednici zasjati poput sunca u kraljevstvu Oca svojega.” “Tko ima uši, neka čuje!”"},{"v":44,"t":"“Kraljevstvo je nebesko kao kad je blago skriveno na njivi: čovjek ga pronađe, sakrije, sav radostan ode, proda sve što ima i kupi tu njivu.”"},{"v":45,"t":"“Nadalje, kraljevstvo je nebesko kao kad trgovac traga za lijepim biserjem:"},{"v":46,"t":"pronađe jedan dragocjeni biser, ode, rasproda sve što ima i kupi ga.”"},{"v":47,"t":"“Nadalje, kraljevstvo je nebesko kao kad mreža bačena u more zahvati svakovrsne ribe."},{"v":48,"t":"Kad se napuni, izvuku je na obalu, sjednu i skupe dobre u posude, a loše izbace."},{"v":49,"t":"Tako će biti na svršetku svijeta. Izići će anđeli, odijeliti zle od pravednih"},{"v":50,"t":"i baciti ih u peć ognjenu, gdje će biti plač i škrgut zubi.”"},{"v":51,"t":"“Jeste li sve ovo razumjeli?” Odgovore mu: “Jesmo.”"},{"v":52,"t":"A on će im: “Stoga svaki pismoznanac upućen u kraljevstvo nebesko sličan je čovjeku domaćinu koji iz svoje riznice iznosi novo i staro.”"},{"v":53,"t":"Kad Isus završi sve ove prispodobe, ode odande."},{"v":54,"t":"I dođe u svoj zavičaj. Naučavaše ih u njihovoj sinagogi te zapanjeni govorahu: “Odakle ovomu ta mudrost i te čudesne sile?"},{"v":55,"t":"Nije li ovo drvodjeljin sin? Nije li mu majka Marija, a braća Jakov, i Josip, i Šimun, i Juda?"},{"v":56,"t":"I sestre mu nisu li sve među nama? Odakle mu sve to?”"},{"v":57,"t":"I sablažnjavahu se o njega. A Isus im reče: “Nije prorok bez časti doli u svom zavičaju i u svom domu.”"},{"v":58,"t":"I ne učini ondje mnogo čudesa zbog njihove nevjere."}]},"14":{"fa":[{"v":1,"t":"در آن هنگام هیرودیس تیترارخ چون شهرت عیسی را شنید،"},{"v":2,"t":"به خادمان خود گفت: «این است یحیی تعمید‌دهنده که ازمردگان برخاسته است، و از این جهت معجزات از او صادر می‌گردد.»"},{"v":3,"t":"زیرا که هیرودیس یحیی را بخاطر هیرودیا، زن برادر خود فیلپس گرفته، در بند نهاده و در زندان انداخته بود؛"},{"v":4,"t":"چون که یحیی بدو همی گفت: «نگاه داشتن وی بر تو حلال نیست.»"},{"v":5,"t":"و وقتی که قصد قتل او کرد، از مردم ترسید زیرا که او را نبی می‌دانستند."},{"v":6,"t":"اما چون بزم میلاد هیرودیس را می‌آراستند، دختر هیرودیا درمجلس رقص کرده، هیرودیس را شاد نمود."},{"v":7,"t":"از این‌رو قسم خورده، وعده داد که آنچه خواهدبدو بدهد."},{"v":8,"t":"و او از ترغیب مادر خود گفت که «سریحیی تعمید‌دهنده را الان در طبقی به من عنایت فرما.»"},{"v":9,"t":"آنگاه پادشاه برنجید، لیکن بجهت پاس قسم و خاطر همنشینان خود، فرمود که بدهند."},{"v":10,"t":"و فرستاده، سر یحیی را در زندان از تن جدا کرد،"},{"v":11,"t":"و سر او را در طشتی گذارده، به دختر تسلیم نمودند و او آن را نزد مادر خود برد."},{"v":12,"t":"پس شاگردانش آمده، جسد او را برداشته، به خاک سپردند و رفته، عیسی را اطلاع دادند."},{"v":13,"t":"و چون عیسی این را شنید، به کشتی سوارشده، از آنجا به ویرانه‌ای به خلوت رفت. و چون مردم شنیدند، از شهرها به راه خشکی از عقب وی روانه شدند."},{"v":14,"t":"پس عیسی بیرون آمده، گروهی بسیار دیده، بر ایشان رحم فرمود وبیماران ایشان را شفا داد."},{"v":15,"t":"و در وقت عصر، شاگردانش نزد وی آمده، گفتند: «این موضع ویرانه است و وقت الان گذشته. پس این گروه رامرخص فرما تا به دهات رفته بجهت خود غذابخرند.»"},{"v":16,"t":"عیسی ایشان را گفت: «احتیاج به رفتن ندارند. شما ایشان را غذا دهید.»"},{"v":17,"t":"بدو گفتند: «در اینجا جز پنج نان و دو ماهی نداریم!»"},{"v":18,"t":"گفت: «آنها را اینجا به نزد من بیاورید!»"},{"v":19,"t":"وبدان جماعت فرمود تا بر سبزه نشستند و پنج نان و دو ماهی را گرفته، به سوی آسمان نگریسته، برکت داد و نان را پاره کرده، به شاگردان سپرد وشاگردان بدان جماعت."},{"v":20,"t":"و همه خورده، سیر شدند و از پاره های باقی‌مانده دوازده سبد پرکرده، برداشتند."},{"v":21,"t":"و خورندگان سوای زنان واطفال قریب به پنج هزار مرد بودند."},{"v":22,"t":"بی‌درنگ عیسی شاگردان خود را اصرارنمود تا به کشتی سوار شده، پیش از وی به کناره دیگر روانه شوند تا آن گروه را رخصت دهد."},{"v":23,"t":"وچون مردم را روانه نمود، به خلوت برای عبادت بر فراز کوهی برآمد. و وقت شام در آنجا تنها بود."},{"v":24,"t":"اما کشتی در آن وقت در میان دریا به‌سبب بادمخالف که می‌وزید، به امواج گرفتار بود."},{"v":25,"t":"و درپاس چهارم از شب، عیسی بر دریا خرامیده، به سوی ایشان روانه گردید."},{"v":26,"t":"اما چون شاگردان، او را بر دریا خرامان دیدند، مضطرب شده، گفتندکه خیالی است؛ و از خوف فریاد برآوردند."},{"v":27,"t":"اماعیسی ایشان را بی‌تامل خطاب کرده، گفت: «خاطر جمع دارید! منم ترسان مباشید!»"},{"v":28,"t":"پطرس در جواب او گفت: «خداوندا، اگر تویی مرا بفرما تا بر روی آب، نزد تو آیم.»"},{"v":29,"t":"گفت: «بیا!» در ساعت پطرس از کشتی فرود شده، برروی آب روانه شد تا نزد عیسی آید."},{"v":30,"t":"لیکن چون باد را شدید دید، ترسان گشت و مشرف به غرق شده، فریاد برآورده، گفت: «خداوندا مرادریاب.»"},{"v":31,"t":"عیسی بی‌درنگ دست آورده، او رابگرفت و گفت: «ای کم‌ایمان، چرا شک آوردی؟»"},{"v":32,"t":"و چون به کشتی سوار شدند، بادساکن گردید."},{"v":33,"t":"پس اهل کشتی آمده، او راپرستش کرده، گفتند: «فی الحقیقه تو پسر خدا هستی!»"},{"v":34,"t":"آنگاه عبور کرده، به زمین جنیسره آمدند،"},{"v":35,"t":"و اهل آن موضع او را شناخته، به همگی آن نواحی فرستاده، همه بیماران را نزد او آوردند،"},{"v":36,"t":"و از او اجازت خواستند که محض دامن ردایش را لمس کنند و هر‌که لمس کرد، صحت کامل یافت."}],"en":[{"v":1,"t":"At that time, Herod the tetrarch heard the report concerning Jesus,"},{"v":2,"t":"and said to his servants, “This is John the Baptizer. He is risen from the dead. That is why these powers work in him.”"},{"v":3,"t":"For Herod had arrested John, bound him, and put him in prison for the sake of Herodias, his brother Philip’s wife."},{"v":4,"t":"For John said to him, “It is not lawful for you to have her.”"},{"v":5,"t":"When he would have put him to death, he feared the multitude, because they counted him as a prophet."},{"v":6,"t":"But when Herod’s birthday came, the daughter of Herodias danced among them and pleased Herod."},{"v":7,"t":"Therefore he promised with an oath to give her whatever she should ask."},{"v":8,"t":"She, being prompted by her mother, said, “Give me here on a platter the head of John the Baptizer.”"},{"v":9,"t":"The king was grieved, but for the sake of his oaths and of those who sat at the table with him, he commanded it to be given,"},{"v":10,"t":"and he sent and beheaded John in the prison."},{"v":11,"t":"His head was brought on a platter and given to the young lady; and she brought it to her mother."},{"v":12,"t":"His disciples came, took the body, and buried it. Then they went and told Jesus."},{"v":13,"t":"Now when Jesus heard this, he withdrew from there in a boat to a deserted place apart. When the multitudes heard it, they followed him on foot from the cities."},{"v":14,"t":"Jesus went out, and he saw a great multitude. He had compassion on them and healed their sick."},{"v":15,"t":"When evening had come, his disciples came to him, saying, “This place is deserted, and the hour is already late. Send the multitudes away, that they may go into the villages, and buy themselves food.”"},{"v":16,"t":"But Jesus said to them, “They don’t need to go away. You give them something to eat.”"},{"v":17,"t":"They told him, “We only have here five loaves and two fish.”"},{"v":18,"t":"He said, “Bring them here to me.”"},{"v":19,"t":"He commanded the multitudes to sit down on the grass; and he took the five loaves and the two fish, and looking up to heaven, he blessed, broke and gave the loaves to the disciples; and the disciples gave to the multitudes."},{"v":20,"t":"They all ate and were filled. They took up twelve baskets full of that which remained left over from the broken pieces."},{"v":21,"t":"Those who ate were about five thousand men, in addition to women and children."},{"v":22,"t":"Immediately Jesus made the disciples get into the boat and go ahead of him to the other side, while he sent the multitudes away."},{"v":23,"t":"After he had sent the multitudes away, he went up into the mountain by himself to pray. When evening had come, he was there alone."},{"v":24,"t":"But the boat was now in the middle of the sea, distressed by the waves, for the wind was contrary."},{"v":25,"t":"In the fourth watch of the night, Jesus came to them, walking on the sea."},{"v":26,"t":"When the disciples saw him walking on the sea, they were troubled, saying, “It’s a ghost!” and they cried out for fear."},{"v":27,"t":"But immediately Jesus spoke to them, saying, “Cheer up! It is I! Don’t be afraid.”"},{"v":28,"t":"Peter answered him and said, “Lord, if it is you, command me to come to you on the waters.”"},{"v":29,"t":"He said, “Come!” Peter stepped down from the boat and walked on the waters to come to Jesus."},{"v":30,"t":"But when he saw that the wind was strong, he was afraid, and beginning to sink, he cried out, saying, “Lord, save me!”"},{"v":31,"t":"Immediately Jesus stretched out his hand, took hold of him, and said to him, “You of little faith, why did you doubt?”"},{"v":32,"t":"When they got up into the boat, the wind ceased."},{"v":33,"t":"Those who were in the boat came and worshiped him, saying, “You are truly the Son of God!”"},{"v":34,"t":"When they had crossed over, they came to the land of Gennesaret."},{"v":35,"t":"When the people of that place recognized him, they sent into all that surrounding region and brought to him all who were sick;"},{"v":36,"t":"and they begged him that they might just touch the fringe of his garment. As many as touched it were made whole."}],"hr":[{"v":1,"t":"U ono vrijeme doču Herod tetrarh za Isusa"},{"v":2,"t":"pa reče svojim slugama: “To je Ivan Krstitelj! On uskrsnu od mrtvih i zato čudesne sile djeluju u njemu.”"},{"v":3,"t":"Herod doista bijaše uhitio Ivana te ga svezana bacio u tamnicu zbog Herodijade, žene brata svoga Filipa."},{"v":4,"t":"Jer Ivan mu govoraše: “Ne smiješ je imati!”"},{"v":5,"t":"Htjede ga ubiti, ali se bojao naroda jer su ga smatrali prorokom."},{"v":6,"t":"Na Herodov rođendan zaplesa kći Herodijadina pred svima i svidje se Herodu."},{"v":7,"t":"Zato se zakle dati joj što god zaište."},{"v":8,"t":"A ona nagovorena od matere: “Daj mi, reče, ovdje na pladnju glavu Ivana Krstitelja.”"},{"v":9,"t":"Ražalosti se kralj, ali zbog zakletve i sustolnika zapovjedi da se dade."},{"v":10,"t":"Posla odrubiti glavu Ivanu u tamnici."},{"v":11,"t":"I doniješe glavu njegovu na pladnju, dadoše djevojci, a ona je odnije materi."},{"v":12,"t":"A učenici njegovi dođu, uzmu njegovo tijelo i pokopaju ga pa odu i jave Isusu."},{"v":13,"t":"Kad je Isus to čuo, povuče se odande lađom na samotno mjesto, u osamu. Dočuo to narod pa pohrli pješice za njim iz gradova."},{"v":14,"t":"Kad on iziđe, vidje silan svijet, sažali mu se nad njim te izliječi njegove bolesnike."},{"v":15,"t":"Uvečer mu pristupe učenici pa mu reknu: “Pust je ovo kraj i već je kasno. Otpusti dakle svijet: neka odu po selima kupiti hrane.”"},{"v":16,"t":"A Isus im reče: “Ne treba da idu, dajte im vi jesti.”"},{"v":17,"t":"Oni mu kažu: “Nemamo ovdje ništa osim pet kruhova i dvije ribe.”"},{"v":18,"t":"A on će im: “Donesite mi ih ovamo.”"},{"v":19,"t":"I zapovjedi da mnoštvo posjeda po travi. On uze pet kruhova i dvije ribe, pogleda na nebo, izreče blagoslov pa razlomi i dade kruhove učenicima, a učenici mnoštvu."},{"v":20,"t":"I jeli su svi i nasitili se. Od preteklih ulomaka nakupiše dvanaest punih košara."},{"v":21,"t":"A blagovalo je oko pet tisuća muškaraca, osim žena i djece."},{"v":22,"t":"I odmah prisili učenike da uđu u lađu i da se prebace prijeko dok on otpusti mnoštvo."},{"v":23,"t":"A pošto otpusti mnoštvo, uziđe na goru, nasamo, da se pomoli. Uvečer bijaše ondje sam."},{"v":24,"t":"Lađa se već mnogo stadija bila ostisla od kraja, šibana valovima. Bijaše protivan vjetar."},{"v":25,"t":"O četvrtoj noćnoj straži dođe on k njima hodeći po moru."},{"v":26,"t":"A učenici ugledavši ga kako hodi po moru, prestrašeni rekoše: “Utvara!” I od straha kriknuše."},{"v":27,"t":"Isus im odmah progovori: “Hrabro samo! Ja sam! Ne bojte se!”"},{"v":28,"t":"Petar prihvati i reče: “Gospodine, ako si ti, zapovjedi mi da dođem k tebi po vodi!”"},{"v":29,"t":"A on mu reče: “Dođi!” I Petar siđe s lađe te, hodeći po vodi, pođe k Isusu."},{"v":30,"t":"Ali kad spazi vjetar, poplaši se, počne tonuti te krikne: “Gospodine, spasi me!”"},{"v":31,"t":"Isus odmah pruži ruku, dohvati ga i kaže mu: “Malovjerni, zašto si posumnjao?”"},{"v":32,"t":"Kad uđoše u lađu, utihnu vjetar."},{"v":33,"t":"A oni na lađi poklone mu se ničice govoreći: “Uistinu, ti si Sin Božji!”"},{"v":34,"t":"Pošto preploviše, dođu na kraj, u Genezaret."},{"v":35,"t":"I ljudi ga onoga kraja prepoznaju pa razglase po svoj onoj okolici. I donošahu mu sve bolesnike"},{"v":36,"t":"te ga moljahu da se samo dotaknu skuta njegove haljine. I koji bi se dotakli, ozdravili bi."}]},"15":{"fa":[{"v":1,"t":"آنگاه کاتبان و فریسیان اورشلیم نزدعیسی آمده، گفتند:"},{"v":2,"t":"«چون است که شاگردان تو از تقلید مشایخ تجاوز می‌نمایند، زیرا هرگاه نان می‌خورند دست خود رانمی شویند؟»"},{"v":3,"t":"او در جواب ایشان گفت: «شمانیز به تقلید خویش، از حکم خدا چرا تجاوزمی کنید؟"},{"v":4,"t":"زیرا خدا حکم داده است که مادر وپدر خود را حرمت دار و هرکه پدر یا مادر رادشنام دهد البته هلاک گردد."},{"v":5,"t":"لیکن شمامی گویید هر‌که پدر یا مادر خود را گوید آنچه ازمن به تو نفع رسد هدیه‌ای است،"},{"v":6,"t":"و پدر یا مادرخود را بعد از آن احترام نمی نماید. پس به تقلیدخود، حکم خدا را باطل نموده‌اید."},{"v":7,"t":"‌ای ریاکاران، اشعیاء در باره شما نیکو نبوت نموده است که گفت:"},{"v":8,"t":"این قوم به زبانهای خود به من تقرب می‌جویند و به لبهای خویش مرا تمجیدمی نمایند، لیکن دلشان از من دور است."},{"v":9,"t":"پس عبادت مرا عبث می‌کنند زیرا که احکام مردم رابمنزله فرایض تعلیم می‌دهند.»"},{"v":10,"t":"و آن جماعت را خوانده، بدیشان گفت: «گوش داده، بفهمید؛"},{"v":11,"t":"نه آنچه به دهان فرومی رود انسان را نجس می‌سازد بلکه آنچه از دهان بیرون می‌آید انسان را نجس می‌گرداند.»"},{"v":12,"t":"آنگاه شاگردان وی آمده، گفتند: «آیا می‌دانی که فریسیان چون این سخن را شنیدند، مکروهش داشتند؟»"},{"v":13,"t":"او در جواب گفت: «هر نهالی که پدرآسمانی من نکاشته باشد، کنده شود."},{"v":14,"t":"ایشان راواگذارید، کوران راهنمایان کورانند و هرگاه کور، کور را راهنما شود، هر دو در چاه افتند."},{"v":15,"t":"پطرس در جواب او گفت: «این مثل را برای ما شرح فرما.»"},{"v":16,"t":"عیسی گفت: «آیا شما نیز تا به حال بی‌ادراک هستید؟"},{"v":17,"t":"یا هنوز نیافته‌اید که آنچه از دهان فرو می‌رود، داخل شکم می‌گردد ودر مبرز افکنده می‌شود؟"},{"v":18,"t":"لیکن آنچه از دهان برآید، از دل صادر می‌گردد و این چیزها است که انسان را نجس می‌سازد."},{"v":19,"t":"زیرا که از دل برمی آید، خیالات بد و قتلها و زناها و فسقها ودزدیها و شهادات دروغ و کفرها."},{"v":20,"t":"اینها است که انسان را نجس می‌سازد، لیکن خوردن به‌دستهای ناشسته، انسان را نجس نمی گرداند.»"},{"v":21,"t":"پس عیسی از آنجا بیرون شده، به دیارصور و صیدون رفت."},{"v":22,"t":"ناگاه زن کنعانیه‌ای از آن حدود بیرون آمده، فریاد‌کنان وی را گفت: «خداوندا، پسر داودا، بر من رحم کن زیرا دختر من سخت دیوانه است.»"},{"v":23,"t":"لیکن هیچ جوابش نداد تا شاگردان او پیش آمده، خواهش نمودند که «او را مرخص فرمای زیرا در عقب ما شورش می‌کند.»"},{"v":24,"t":"او در جواب گفت: «فرستاده نشده‌ام مگر بجهت گوسفندان گم شده خاندان اسرائیل.»"},{"v":25,"t":"پس آن زن آمده، او را پرستش کرده، گفت: «خداوندا مرا یاری کن.»"},{"v":26,"t":"در جواب گفت که «نان فرزندان را گرفتن و نزد سگان انداختن جایزنیست.»"},{"v":27,"t":"عرض کرد: «بلی خداوندا، زیرا سگان نیز از پاره های افتاده سفره آقایان خویش می‌خورند.»"},{"v":28,"t":"آنگاه عیسی در جواب او گفت: «ای زن! ایمان تو عظیم است! تو را برحسب خواهش تو بشود.» که در همان ساعت، دخترش شفا یافت."},{"v":29,"t":"عیسی از آنجا حرکت کرده، به کناره دریای جلیل آمد و برفراز کوه برآمده، آنجا بنشست."},{"v":30,"t":"و گروهی بسیار، لنگان و کوران و گنگان وشلان و جمعی از دیگران را با خود برداشته، نزداو آمدند و ایشان را بر پایهای عیسی افکندند وایشان را شفا داد،"},{"v":31,"t":"بقسمی که آن جماعت، چون گنگان را گویا و شلان را تندرست و لنگان راخرامان و کوران را بینا دیدند، متعجب شده، خدای اسرائیل را تمجید کردند."},{"v":32,"t":"عیسی شاگردان خود را پیش طلبیده، گفت: «مرا بر این جماعت دل بسوخت زیرا که الحال سه روز است که با من می‌باشند و هیچ‌چیز برای خوراک ندارند و نمی خواهم ایشان را گرسنه برگردانم مبادا در راه ضعف کنند.»"},{"v":33,"t":"شاگردانش به او گفتند: «از کجا در بیابان ما را آنقدر نان باشدکه چنین انبوه را سیر کند؟»"},{"v":34,"t":"عیسی ایشان راگفت: «چند نان دارید؟» گفتند: «هفت نان و قدری از ماهیان کوچک.»"},{"v":35,"t":"پس مردم را فرمود تا برزمین بنشینند."},{"v":36,"t":"و آن هفت نان و ماهیان را گرفته، شکر نمود و پاره کرده، به شاگردان خود داد وشاگردان به آن جماعت."},{"v":37,"t":"و همه خورده، سیرشدند و از خرده های باقی‌مانده هفت زنبیل پربرداشتند."},{"v":38,"t":"و خورندگان، سوای زنان و اطفال چهار هزار مرد بودند."},{"v":39,"t":"پس آن گروه را رخصت داد و به کشتی سوار شده، به حدود مجدل آمد."}],"en":[{"v":1,"t":"Then Pharisees and scribes came to Jesus from Jerusalem, saying,"},{"v":2,"t":"“Why do your disciples disobey the tradition of the elders? For they don’t wash their hands when they eat bread.”"},{"v":3,"t":"He answered them, “Why do you also disobey the commandment of God because of your tradition?"},{"v":4,"t":"For God commanded, ‘Honor your father and your mother,’ and, ‘He who speaks evil of father or mother, let him be put to death.’"},{"v":5,"t":"But you say, ‘Whoever may tell his father or his mother, “Whatever help you might otherwise have gotten from me is a gift devoted to God,”"},{"v":6,"t":"he shall not honor his father or mother.’ You have made the commandment of God void because of your tradition."},{"v":7,"t":"You hypocrites! Well did Isaiah prophesy of you, saying,"},{"v":8,"t":"‘These people draw near to me with their mouth, and honor me with their lips; but their heart is far from me."},{"v":9,"t":"And they worship me in vain, teaching as doctrine rules made by men.’”"},{"v":10,"t":"He summoned the multitude, and said to them, “Hear, and understand."},{"v":11,"t":"That which enters into the mouth doesn’t defile the man; but that which proceeds out of the mouth, this defiles the man.”"},{"v":12,"t":"Then the disciples came and said to him, “Do you know that the Pharisees were offended when they heard this saying?”"},{"v":13,"t":"But he answered, “Every plant which my heavenly Father didn’t plant will be uprooted."},{"v":14,"t":"Leave them alone. They are blind guides of the blind. If the blind guide the blind, both will fall into a pit.”"},{"v":15,"t":"Peter answered him, “Explain the parable to us.”"},{"v":16,"t":"So Jesus said, “Do you also still not understand?"},{"v":17,"t":"Don’t you understand that whatever goes into the mouth passes into the belly and then out of the body?"},{"v":18,"t":"But the things which proceed out of the mouth come out of the heart, and they defile the man."},{"v":19,"t":"For out of the heart come evil thoughts, murders, adulteries, sexual sins, thefts, false testimony, and blasphemies."},{"v":20,"t":"These are the things which defile the man; but to eat with unwashed hands doesn’t defile the man.”"},{"v":21,"t":"Jesus went out from there and withdrew into the region of Tyre and Sidon."},{"v":22,"t":"Behold, a Canaanite woman came out from those borders and cried, saying, “Have mercy on me, Lord, you son of David! My daughter is severely possessed by a demon!”"},{"v":23,"t":"But he answered her not a word. His disciples came and begged him, saying, “Send her away; for she cries after us.”"},{"v":24,"t":"But he answered, “I wasn’t sent to anyone but the lost sheep of the house of Israel.”"},{"v":25,"t":"But she came and worshiped him, saying, “Lord, help me.”"},{"v":26,"t":"But he answered, “It is not appropriate to take the children’s bread and throw it to the dogs.”"},{"v":27,"t":"But she said, “Yes, Lord, but even the dogs eat the crumbs which fall from their masters’ table.”"},{"v":28,"t":"Then Jesus answered her, “Woman, great is your faith! Be it done to you even as you desire.” And her daughter was healed from that hour."},{"v":29,"t":"Jesus departed from there and came near to the sea of Galilee; and he went up on the mountain and sat there."},{"v":30,"t":"Great multitudes came to him, having with them the lame, blind, mute, maimed, and many others, and they put them down at his feet. He healed them,"},{"v":31,"t":"so that the multitude wondered when they saw the mute speaking, the injured healed, the lame walking, and the blind seeing—and they glorified the God of Israel."},{"v":32,"t":"Jesus summoned his disciples and said, “I have compassion on the multitude, because they have continued with me now three days and have nothing to eat. I don’t want to send them away fasting, or they might faint on the way.”"},{"v":33,"t":"The disciples said to him, “Where could we get so many loaves in a deserted place as to satisfy so great a multitude?”"},{"v":34,"t":"Jesus said to them, “How many loaves do you have?” They said, “Seven, and a few small fish.”"},{"v":35,"t":"He commanded the multitude to sit down on the ground;"},{"v":36,"t":"and he took the seven loaves and the fish. He gave thanks and broke them, and gave to the disciples, and the disciples to the multitudes."},{"v":37,"t":"They all ate and were filled. They took up seven baskets full of the broken pieces that were left over."},{"v":38,"t":"Those who ate were four thousand men, in addition to women and children."},{"v":39,"t":"Then he sent away the multitudes, got into the boat, and came into the borders of Magdala."}],"hr":[{"v":1,"t":"Tada pristupe Isusu farizeji i pismoznanci iz Jeruzalema govoreći:"},{"v":2,"t":"“Zašto tvoji učenici prestupaju predaju starih? Ne umivaju ruku prije jela!”"},{"v":3,"t":"On im odgovori: “A zašto vi prestupate zapovijed Božju radi svoje predaje?"},{"v":4,"t":"Ta reče Bog: Poštuj oca i majku! I: Tko prokune oca ili majku, smrću neka se kazni!"},{"v":5,"t":"A vi velite: 'Rekne li tko ocu ili majci: Pomoć koja te od mene ide neka bude sveti dar,"},{"v":6,"t":"ne treba da poštuje oca svoga ni majku svoju.' Tako dokinuste riječ Božju radi svoje predaje."},{"v":7,"t":"Licemjeri, dobro prorokova o vama Izaija:"},{"v":8,"t":"Narod me ovaj usnama časti, a srce mu je daleko od mene."},{"v":9,"t":"Uzalud me štuju naučavajući nauke - uredbe ljudske.”"},{"v":10,"t":"Tada dozove mnoštvo i reče: “Slušajte i razumijte!"},{"v":11,"t":"Ne onečišćuje čovjeka što ulazi u usta, nego što iz usta izlazi - to čovjeka onečišćuje.”"},{"v":12,"t":"Tada pristupe k njemu učenici i kažu mu: “Znaš li da su se farizeji sablaznili kad su čuli tu riječ?”"},{"v":13,"t":"On im odgovori: “Svaki nasad koji ne posadi Otac moj nebeski iskorijenit će se."},{"v":14,"t":"Pustite ih! Slijepi su, vođe slijepaca! A ako slijepac slijepca vodi, obojica će u jamu pasti.”"},{"v":15,"t":"Petar prihvati i reče mu: “Protumači nam tu prispodobu!”"},{"v":16,"t":"A on reče: “I vi još uvijek ne razumijete?"},{"v":17,"t":"Ne shvaćate li: sve što ulazi na usta, ide u trbuh te se izbacuje u zahod."},{"v":18,"t":"Naprotiv, što iz usta izlazi, iz srca izvire i to onečišćuje čovjeka."},{"v":19,"t":"Ta iz srca izviru opake namisli, ubojstva, preljubi, bludništva, krađe, lažna svjedočanstva, psovke."},{"v":20,"t":"To onečišćuje čovjeka; a jesti neopranih ruku ne onečišćuje čovjeka.”"},{"v":21,"t":"Isus zatim ode odande i povuče se u krajeve tirske i sidonske."},{"v":22,"t":"I gle: žena neka, Kanaanka iz onih krajeva, iziđe vičući: “Smiluj mi se, Gospodine, Sine Davidov! Kći mi je teško opsjednuta!”"},{"v":23,"t":"Ali on joj ne uzvrati ni riječi. Pristupe mu na to učenici te ga moljahu: “Udovolji joj jer viče za nama.”"},{"v":24,"t":"On odgovori: “Poslan sam samo k izgubljenim ovcama doma Izraelova.”"},{"v":25,"t":"Ali ona priđe, pokloni mu se ničice i kaže: “Gospodine, pomozi mi!”"},{"v":26,"t":"On odgovori: “Ne priliči uzeti kruh djeci i baciti ga psićima.”"},{"v":27,"t":"A ona će: “Da, Gospodine! Ali psići jedu od mrvica što padaju sa stola njihovih gospodara!”"},{"v":28,"t":"Tada joj Isus reče: “O ženo! Velika je vjera tvoja! Neka ti bude kako želiš.” I ozdravi joj kći toga časa."},{"v":29,"t":"Otišavši odande, dođe Isus do Galilejskog mora, uziđe na goru i sjede ondje."},{"v":30,"t":"Tada nagrnu k njemu silan svijet s hromima, kljastima, slijepima, nijemima i mnogima drugima. Polože mu ih do nogu, a on ih izliječi."},{"v":31,"t":"Gledajući kako su nijemi progovorili, kljasti ozdravili, hromi prohodali, slijepi progledali, divilo se mnoštvo i slavilo Boga Izraelova."},{"v":32,"t":"A Isus dozva svoje učenike pa im reče: “Žao mi je naroda jer su već tri dana uza me, a nemaju što jesti. Otpraviti ih gladne neću da ne klonu putem.”"},{"v":33,"t":"Kažu mu učenici: “Odakle nam u pustinji toliko kruha da nahranimo toliko mnoštvo?”"},{"v":34,"t":"A Isus im reče: “Koliko kruhova imate?” Oni će: “Sedam, i malo riba.”"},{"v":35,"t":"Nato zapovjedi mnoštvu da posjeda po zemlji,"},{"v":36,"t":"uze sedam kruhova i ribe, zahvali, razlomi i davaše učenicima, a učenici mnoštvu."},{"v":37,"t":"I jeli su i nasitili se. A od preteklih ulomaka nakupiše sedam punih košara."},{"v":38,"t":"A blagovalo je četiri tisuće muškaraca, osim žena i djece."},{"v":39,"t":"Tada otpusti mnoštvo, uđe u lađu i ode u kraj magadanski."}]},"16":{"fa":[{"v":1,"t":"آنگاه فریسیان و صدوقیان نزد او آمده، از روی امتحان از وی خواستند که آیتی آسمانی برای ایشان ظاهر سازد."},{"v":2,"t":"ایشان راجواب داد که «در وقت عصر می‌گویید هوا خوش خواهد بود زیرا آسمان سرخ است؛"},{"v":3,"t":"وصبحگاهان می‌گویید امروز هوا بد خواهد شدزیرا که آسمان سرخ و گرفته است. ای ریاکاران می‌دانید صورت آسمان را تمییز دهید، اماعلامات زمانها را نمی توانید!"},{"v":4,"t":"فرقه شریر زناکار، آیتی می‌طلبند و آیتی بدیشان عطا نخواهد شدجز آیت یونس نبی.» پس ایشان را رها کرده، روانه شد."},{"v":5,"t":"و شاگردانش چون بدان طرف می‌رفتند، فراموش کردند که نان بردارند."},{"v":6,"t":"عیسی ایشان راگفت: «آگاه باشید که از خمیرمایه فریسیان وصدوقیان احتیاط کنید!»"},{"v":7,"t":"پس ایشان در خودتفکر نموده، گفتند: «از آن است که نان برنداشته‌ایم.»"},{"v":8,"t":"عیسی این را درک نموده، بدیشان گفت: «ای سست‌ایمانان، چرا در خود تفکرمی کنید از آنجهت که نان نیاورده‌اید؟"},{"v":9,"t":"آیا هنوزنفهمیده و یاد نیاورده‌اید آن پنج نان و پنج هزارنفر و چند سبدی را که برداشتید؟"},{"v":10,"t":"و نه آن هفت نان و چهار هزار نفر و چند زنبیلی را که برداشتید؟»"},{"v":11,"t":"پس چرا نفهمیدید که درباره نان شما را نگفتم که از خمیرمایه فریسیان وصدوقیان احتیاط کنید؟»"},{"v":12,"t":"آنگاه دریافتند که نه از خمیرمایه نان بلکه از تعلیم فریسیان وصدوقیان حکم به احتیاط فرموده است."},{"v":13,"t":"و هنگامی که عیسی به نواحی قیصریه فیلپس آمد، از شاگردان خود پرسیده، گفت: «مردم مرا که پسر انسانم چه شخص می‌گویند؟»"},{"v":14,"t":"گفتند: «بعضی یحیی تعمید‌دهنده و بعضی الیاس و بعضی ارمیا یا یکی از انبیا.»"},{"v":15,"t":"ایشان راگفت: «شما مرا که می‌دانید؟»"},{"v":16,"t":"شمعون پطرس در جواب گفت که «تویی مسیح، پسر خدای زنده!»"},{"v":17,"t":"عیسی در جواب وی گفت: «خوشابحال تو‌ای شمعون بن یونا! زیرا جسم وخون این را بر تو کشف نکرده، بلکه پدر من که درآسمان است."},{"v":18,"t":"و من نیز تو را می‌گویم که تویی پطرس و بر این صخره کلیسای خود را بنا می‌کنم و ابواب جهنم بر آن استیلا نخواهد یافت."},{"v":19,"t":"وکلیدهای ملکوت آسمان را به تو می‌سپارم؛ وآنچه بر زمین ببندی در آسمان بسته گردد و آنچه در زمین گشایی در آسمان گشاده شود."},{"v":20,"t":"آنگاه شاگردان خود را قدغن فرمود که به هیچ‌کس نگویند که او مسیح است."},{"v":21,"t":"و از آن زمان عیسی به شاگردان خودخبردادن آغاز کرد که رفتن او به اورشلیم وزحمت بسیار کشیدن از مشایخ و روسای کهنه وکاتبان و کشته شدن و در روز سوم برخاستن ضروری است."},{"v":22,"t":"و پطرس او را گرفته، شروع کرد به منع نمودن و گفت: «حاشا از تو‌ای خداوندکه این بر تو هرگز واقع نخواهد شد!»"},{"v":23,"t":"اما اوبرگشته، پطرس را گفت: «دور شو از من‌ای شیطان زیرا که باعث لغزش من می‌باشی، زیرا نه امورالهی را بلکه امور انسانی را تفکر می‌کنی!»"},{"v":24,"t":"آنگاه عیسی به شاگردان خود گفت: «اگر کسی خواهدمتابعت من کند، باید خود را انکار کرده وصلیب خود را برداشته، از عقب من آید."},{"v":25,"t":"زیرا هر کس بخواهد جان خود را برهاند، آن را هلاک سازد؛ اما هر‌که جان خود را بخاطر من هلاک کند، آن را دریابد."},{"v":26,"t":"زیرا شخص را چه سود دارد که تمام دنیا را ببرد و جان خود را ببازد؟ یا اینکه آدمی چه چیز را فدای جان خود خواهدساخت؟"},{"v":27,"t":"زیرا که پسر انسان خواهد آمد درجلال پدر خویش به اتفاق ملائکه خود و در آن وقت هر کسی را موافق اعمالش جزا خواهد داد."},{"v":28,"t":"هرآینه به شما می‌گویم که بعضی در اینجاحاضرند که تا پسر انسان را نبینند که در ملکوت خود می‌آید، ذائقه موت را نخواهند چشید.»"}],"en":[{"v":1,"t":"The Pharisees and Sadducees came, and testing him, asked him to show them a sign from heaven."},{"v":2,"t":"But he answered them, “When it is evening, you say, ‘It will be fair weather, for the sky is red.’"},{"v":3,"t":"In the morning, ‘It will be foul weather today, for the sky is red and threatening.’ Hypocrites! You know how to discern the appearance of the sky, but you can’t discern the signs of the times!"},{"v":4,"t":"An evil and adulterous generation seeks after a sign, and there will be no sign given to it, except the sign of the prophet Jonah.” He left them and departed."},{"v":5,"t":"The disciples came to the other side and had forgotten to take bread."},{"v":6,"t":"Jesus said to them, “Take heed and beware of the yeast of the Pharisees and Sadducees.”"},{"v":7,"t":"They reasoned among themselves, saying, “We brought no bread.”"},{"v":8,"t":"Jesus, perceiving it, said, “Why do you reason among yourselves, you of little faith, because you have brought no bread?"},{"v":9,"t":"Don’t you yet perceive or remember the five loaves for the five thousand, and how many baskets you took up,"},{"v":10,"t":"or the seven loaves for the four thousand, and how many baskets you took up?"},{"v":11,"t":"How is it that you don’t perceive that I didn’t speak to you concerning bread? But beware of the yeast of the Pharisees and Sadducees.”"},{"v":12,"t":"Then they understood that he didn’t tell them to beware of the yeast of bread, but of the teaching of the Pharisees and Sadducees."},{"v":13,"t":"Now when Jesus came into the parts of Caesarea Philippi, he asked his disciples, saying, “Who do men say that I, the Son of Man, am?”"},{"v":14,"t":"They said, “Some say John the Baptizer, some, Elijah, and others, Jeremiah or one of the prophets.”"},{"v":15,"t":"He said to them, “But who do you say that I am?”"},{"v":16,"t":"Simon Peter answered, “You are the Christ, the Son of the living God.”"},{"v":17,"t":"Jesus answered him, “Blessed are you, Simon Bar Jonah, for flesh and blood has not revealed this to you, but my Father who is in heaven."},{"v":18,"t":"I also tell you that you are Peter, and on this rock I will build my assembly, and the gates of Hades will not prevail against it."},{"v":19,"t":"I will give to you the keys of the Kingdom of Heaven, and whatever you bind on earth will have been bound in heaven; and whatever you release on earth will have been released in heaven.”"},{"v":20,"t":"Then he commanded the disciples that they should tell no one that he was Jesus the Christ."},{"v":21,"t":"From that time, Jesus began to show his disciples that he must go to Jerusalem and suffer many things from the elders, chief priests, and scribes, and be killed, and the third day be raised up."},{"v":22,"t":"Peter took him aside and began to rebuke him, saying, “Far be it from you, Lord! This will never be done to you.”"},{"v":23,"t":"But he turned and said to Peter, “Get behind me, Satan! You are a stumbling block to me, for you are not setting your mind on the things of God, but on the things of men.”"},{"v":24,"t":"Then Jesus said to his disciples, “If anyone desires to come after me, let him deny himself, take up his cross, and follow me."},{"v":25,"t":"For whoever desires to save his life will lose it, and whoever will lose his life for my sake will find it."},{"v":26,"t":"For what will it profit a man if he gains the whole world and forfeits his life? Or what will a man give in exchange for his life?"},{"v":27,"t":"For the Son of Man will come in the glory of his Father with his angels, and then he will render to everyone according to his deeds."},{"v":28,"t":"Most certainly I tell you, there are some standing here who will in no way taste of death until they see the Son of Man coming in his Kingdom.”"}],"hr":[{"v":1,"t":"Pristupe k njemu farizeji i saduceji. Iskušavajući ga, zatraže da im pokaže kakav znak s neba."},{"v":2,"t":"On im odgovori: “Uvečer govorite: 'Bit će vedro, nebo se žari.'"},{"v":3,"t":"A ujutro: 'Danas će nevrijeme, nebo se tamno zacrvenjelo.' Lice neba znadete rasuditi, a znakove vremena ne znate."},{"v":4,"t":"Naraštaj opak i preljubnički znak traži, ali mu se znak neće dati doli znak Jonin.” Tada ih ostavi i ode."},{"v":5,"t":"Učenici dođoše prijeko, a zaboraviše ponijeti kruha."},{"v":6,"t":"A Isus im reče: “Pazite, čuvajte se kvasca farizejskog i saducejskog!”"},{"v":7,"t":"Oni zamišljeni među sobom govorahu: “Kruha ne ponijesmo.”"},{"v":8,"t":"Zamijetio to Isus pa reče: “Što ste zamišljeni, malovjerni, da kruha nemate?"},{"v":9,"t":"Zar još ne shvaćate, ne sjećate li se onih pet kruhova na pet tisuća i koliko košara nakupiste?"},{"v":10,"t":"I onih sedam kruhova na četiri tisuće i koliko košara nakupiste?"},{"v":11,"t":"Kako onda ne shvaćate da vam to ne rekoh o kruhu? Nego, čuvajte se kvasca farizejskog i saducejskog.”"},{"v":12,"t":"Tada razumješe kako im ne reče da se čuvaju kvasca krušnoga, nego nauka farizejskog i saducejskoga."},{"v":13,"t":"Kad Isus dođe u krajeve Cezareje Filipove, upita učenike: “Što govore ljudi, tko je Sin Čovječji?”"},{"v":14,"t":"Oni rekoše: “Jedni da je Ivan Krstitelj; drugi da je Ilija; treći opet da je Jeremija ili koji od proroka.”"},{"v":15,"t":"Kaže im: “A vi, što vi kažete, tko sam ja?”"},{"v":16,"t":"Šimun Petar prihvati i reče: “Ti si Krist-Pomazanik, Sin Boga živoga.”"},{"v":17,"t":"Nato Isus reče njemu: “Blago tebi, Šimune, sine Jonin, jer ti to ne objavi tijelo i krv, nego Otac moj, koji je na nebesima."},{"v":18,"t":"A ja tebi kažem: Ti si Petar-Stijena i na toj stijeni sagradit ću Crkvu svoju i vrata paklena neće je nadvladati."},{"v":19,"t":"Tebi ću dati ključeve kraljevstva nebeskoga, pa što god svežeš na zemlji, bit će svezano na nebesima; a što god odriješiš na zemlji, bit će odriješeno na nebesima.”"},{"v":20,"t":"Tada zaprijeti učenicima neka nikomu ne reknu da je on Krist."},{"v":21,"t":"Otada poče Isus upućivati učenike kako treba da pođe u Jeruzalem, da mnogo pretrpi od starješina, glavara svećeničkih i pismoznanaca, da bude ubijen i treći dan da uskrsne."},{"v":22,"t":"Petar ga uze na stranu i poče odvraćati: “Bože sačuvaj, Gospodine! Ne, to se tebi ne smije dogoditi!”"},{"v":23,"t":"Isus se okrene i reče Petru: “Nosi se od mene, sotono! Sablazan si mi jer ti nije na pameti što je Božje, nego što je ljudsko!”"},{"v":24,"t":"Tada Isus reče svojim učenicima: “Hoće li tko za mnom, neka se odrekne samoga sebe, neka uzme svoj križ i neka ide za mnom."},{"v":25,"t":"Tko hoće život svoj spasiti, izgubit će ga, a tko izgubi život svoj poradi mena, naći će ga."},{"v":26,"t":"Ta što će koristiti čovjeku ako sav svijet stekne, a životu svojemu naudi? Ili što će čovjek dati u zamjenu za život svoj?"},{"v":27,"t":"Doći će, doista, Sin Čovječji u slavi Oca svoga s anđelima svojim i tada će naplatiti svakomu po djelima njegovim.”"},{"v":28,"t":"“Zaista, kažem vam, neki od ovdje nazočnih neće okusiti smrti dok ne vide Sina Čovječjega gdje dolazi sa svojim kraljevstvom.”"}]},"17":{"fa":[{"v":1,"t":"و بعد از شش روز، عیسی، پطرس ویعقوب و برادرش یوحنا را برداشته، ایشان را در خلوت به کوهی بلند برد."},{"v":2,"t":"و در نظرایشان هیات او متبدل گشت و چهره‌اش چون خورشید، درخشنده و جامه‌اش چون نور، سفیدگردید."},{"v":3,"t":"که ناگاه موسی و الیاس بر ایشان ظاهرشده، با او گفتگو می‌کردند."},{"v":4,"t":"اما پطرس به عیسی متوجه شده، گفت که «خداوندا، بودن ما در اینجانیکو است! اگر بخواهی، سه سایبان در اینجابسازیم، یکی برای تو و یکی بجهت موسی ودیگری برای الیاس.»"},{"v":5,"t":"و هنوز سخن بر زبانش بود که ناگاه ابری درخشنده بر ایشان سایه افکند واینک آوازی از ابر در‌رسید که «این است پسرحبیب من که از وی خشنودم. او را بشنوید!»"},{"v":6,"t":"وچون شاگردان این را شنیدند، به روی در‌افتاده، بینهایت ترسان شدند."},{"v":7,"t":"عیسی نزدیک آمده، ایشان را لمس نمود و گفت: «برخیزید و ترسان مباشید!»"},{"v":8,"t":"و چشمان خود را گشوده، هیچ‌کس راجز عیسی تنها ندیدند."},{"v":9,"t":"و چون ایشان از کوه به زیر می‌آمدند، عیسی ایشان را قدغن فرمود که «تاپسر انسان از مردگان برنخیزد، زنهار این‌رویا را به کسی باز نگویید.»"},{"v":10,"t":"شاگردانش از او پرسیده، گفتند: «پس کاتبان چرا می‌گویند که می‌بایدالیاس اول آید؟»"},{"v":11,"t":"او در جواب گفت: «البته الیاس می‌آید و تمام چیزها را اصلاح خواهدنمود."},{"v":12,"t":"لیکن به شما می‌گویم که الحال الیاس آمده است و او را نشناختند بلکه آنچه خواستندبا وی کردند؛ به همانطور پسر انسان نیز از ایشان زحمت خواهد دید."},{"v":13,"t":"آنگاه شاگردان دریافتندکه درباره یحیی تعمیددهنده بدیشان سخن می‌گفت."},{"v":14,"t":"و چون به نزد جماعت رسیدند، شخصی پیش آمده، نزد وی زانو زده، عرض کرد:"},{"v":15,"t":"«خداوندا، بر پسر من رحم کن زیرا مصروع و به شدت متالم است، چنانکه بارها در آتش و مکرر در آب می‌افتد."},{"v":16,"t":"و او را نزد شاگردان تو آوردم، نتوانستند او را شفا دهند.»"},{"v":17,"t":"عیسی در جواب گفت: «ای فرقه بی‌ایمان کج رفتار، تا به کی با شماباشیم و تا چند متحمل شما گردم؟ او را نزد من آورید.»"},{"v":18,"t":"پس عیسی او را نهیب داده، دیو ازوی بیرون شد و در ساعت، آن پسر شفا یافت."},{"v":19,"t":"اما شاگردان نزد عیسی آمده، در خلوت از اوپرسیدند: «چرا ما نتوانستیم او را بیرون کنیم؟"},{"v":20,"t":"عیسی ایشان را گفت: «به‌سبب بی‌ایمانی شما. زیرا هرآینه به شما می‌گویم، اگر ایمان به قدر دانه خردلی می‌داشتید، بدین کوه می‌گفتید از اینجابدانجا منتقل شو، البته منتقل می‌شد و هیچ امری بر شما محال نمی بود."},{"v":21,"t":"لیکن این جنس جز به دعا و روزه بیرون نمی رود.»"},{"v":22,"t":"و چون ایشان در جلیل می‌گشتند، عیسی بدیشان گفت: «پسر انسان بدست مردم تسلیم کرده خواهد شد،"},{"v":23,"t":"و او را خواهند کشت و درروز سوم خواهد برخاست.» پس بسیار محزون شدند."},{"v":24,"t":"و چون ایشان وارد کفرناحوم شدند، محصلان دو درهم نزد پطرس آمده، گفتند: «آیااستاد شما دو درهم را نمی دهد؟»"},{"v":25,"t":"گفت: «بلی.» و چون به خانه درآمده، عیسی بر او سبقت نموده، گفت: «ای شمعون، چه گمان داری؟ پادشاهان جهان از چه کسان عشر و جزیه می‌گیرند؟ از فرزندان خویش یا از بیگانگان؟»"},{"v":26,"t":"پطرس به وی گفت: «از بیگانگان.» عیسی بدوگفت: «پس یقین پسران آزادند!"},{"v":27,"t":"لیکن مبادا که ایشان را برنجانیم، به کناره دریا رفته، قلابی بینداز و اول ماهی که بیرون می‌آید، گرفته و دهانش راباز کرده، مبلغ چهار درهم خواهی یافت. آن رابرداشته، برای من و خود بدیشان بده!»"}],"en":[{"v":1,"t":"After six days, Jesus took with him Peter, James, and John his brother, and brought them up into a high mountain by themselves."},{"v":2,"t":"He was changed before them. His face shone like the sun, and his garments became as white as the light."},{"v":3,"t":"Behold, Moses and Elijah appeared to them talking with him."},{"v":4,"t":"Peter answered and said to Jesus, “Lord, it is good for us to be here. If you want, let’s make three tents here: one for you, one for Moses, and one for Elijah.”"},{"v":5,"t":"While he was still speaking, behold, a bright cloud overshadowed them. Behold, a voice came out of the cloud, saying, “This is my beloved Son, in whom I am well pleased. Listen to him.”"},{"v":6,"t":"When the disciples heard it, they fell on their faces, and were very afraid."},{"v":7,"t":"Jesus came and touched them and said, “Get up, and don’t be afraid.”"},{"v":8,"t":"Lifting up their eyes, they saw no one, except Jesus alone."},{"v":9,"t":"As they were coming down from the mountain, Jesus commanded them, saying, “Don’t tell anyone what you saw, until the Son of Man has risen from the dead.”"},{"v":10,"t":"His disciples asked him, saying, “Then why do the scribes say that Elijah must come first?”"},{"v":11,"t":"Jesus answered them, “Elijah indeed comes first, and will restore all things;"},{"v":12,"t":"but I tell you that Elijah has come already, and they didn’t recognize him, but did to him whatever they wanted to. Even so the Son of Man will also suffer by them.”"},{"v":13,"t":"Then the disciples understood that he spoke to them of John the Baptizer."},{"v":14,"t":"When they came to the multitude, a man came to him, kneeling down to him and saying,"},{"v":15,"t":"“Lord, have mercy on my son, for he is epileptic and suffers grievously; for he often falls into the fire, and often into the water."},{"v":16,"t":"So I brought him to your disciples, and they could not cure him.”"},{"v":17,"t":"Jesus answered, “Faithless and perverse generation! How long will I be with you? How long will I bear with you? Bring him here to me.”"},{"v":18,"t":"Jesus rebuked the demon, and it went out of him, and the boy was cured from that hour."},{"v":19,"t":"Then the disciples came to Jesus privately, and said, “Why weren’t we able to cast it out?”"},{"v":20,"t":"He said to them, “Because of your unbelief. For most certainly I tell you, if you have faith as a grain of mustard seed, you will tell this mountain, ‘Move from here to there,’ and it will move; and nothing will be impossible for you."},{"v":21,"t":"But this kind doesn’t go out except by prayer and fasting.”"},{"v":22,"t":"While they were staying in Galilee, Jesus said to them, “The Son of Man is about to be delivered up into the hands of men,"},{"v":23,"t":"and they will kill him, and the third day he will be raised up.” They were exceedingly sorry."},{"v":24,"t":"When they had come to Capernaum, those who collected the didrachma coins came to Peter, and said, “Doesn’t your teacher pay the didrachma?”"},{"v":25,"t":"He said, “Yes.” When he came into the house, Jesus anticipated him, saying, “What do you think, Simon? From whom do the kings of the earth receive toll or tribute? From their children, or from strangers?”"},{"v":26,"t":"Peter said to him, “From strangers.” Jesus said to him, “Therefore the children are exempt."},{"v":27,"t":"But, lest we cause them to stumble, go to the sea, cast a hook, and take up the first fish that comes up. When you have opened its mouth, you will find a stater coin. Take that, and give it to them for me and you.”"}],"hr":[{"v":1,"t":"Nakon šest dana uze Isus sa sobom Petra, Jakova i Ivana, brata njegova, te ih povede na goru visoku, u osamu,"},{"v":2,"t":"i preobrazi se pred njima. I zasja mu lice kao sunce, a haljine mu postadoše bijele kao svjetlost."},{"v":3,"t":"I gle: ukazaše im se Mojsije i Ilija te razgovarahu s njime."},{"v":4,"t":"A Petar prihvati i reče Isusu: “Gospodine, dobro nam je ovdje biti. Ako hoćeš, načinit ću ovdje tri sjenice, tebi jednu, Mojsiju jednu i Iliji jednu.”"},{"v":5,"t":"Dok je on još govorio, gle, svijetao ih oblak zasjeni, a glas iz oblaka govoraše: “Ovo je Sin moj, Ljubljeni! U njemu mi sva milina! Slušajte ga!”"},{"v":6,"t":"Čuvši glas, učenici padoše licem na zemlju i silno se prestrašiše."},{"v":7,"t":"Pristupi k njima Isus, dotakne ih i reče: “Ustanite, ne bojte se!”"},{"v":8,"t":"Podigoše oči, ali ne vidješe nikoga doli Isusa sama."},{"v":9,"t":"Dok su silazili s gore, zapovjedi im Isus: “Nikomu ne kazujte viđenje dok Sin Čovječji od mrtvih ne uskrsne.”"},{"v":10,"t":"Upitaše ga učenici: “Što dakle pismoznanci govore da prije treba da dođe Ilija?”"},{"v":11,"t":"On im odgovori: “Ilija će doduše doći i sve obnoviti."},{"v":12,"t":"No velim vam: Ilija je već došao, ali ga ne upoznaše, već učiniše s njim što im se prohtjelo. Tako je i Sinu Čovječjemu trpjeti od njih.”"},{"v":13,"t":"Tada razumješe učenici da im to reče o Ivanu Krstitelju."},{"v":14,"t":"Kada dođoše k mnoštvu, pristupi mu čovjek, padne pred njim na koljena"},{"v":15,"t":"i reče: “Gospodine, smiluj se sinu mojemu jer je mjesečar i zlo mu je. Često doista pada u oganj i često u vodu."},{"v":16,"t":"Dovedoh ga tvojim učenicima i ne mogoše ga izliječiti.”"},{"v":17,"t":"A Isus odgovori: “O rode nevjerni i opaki! Dokle mi je biti s vama! Dokle li vas podnositi! Dovedite mi ga ovamo!”"},{"v":18,"t":"I zaprijeti Isus zloduhu te on iziđe iz njega. I ozdravi dječak toga časa."},{"v":19,"t":"Tada učenici pristupiše nasamo k Isusu i rekoše: “Zašto ga mi ne mogosmo izagnati?”"},{"v":20,"t":"Kaže im: “Zbog vaše malovjernosti. Zaista, kažem vam, ako imadnete vjere koliko je zrno gorušičino te reknete ovoj gori: 'Premjesti se odavde onamo!', premjestit će se i ništa vam neće biti nemoguće.”"},{"v":21,"t":"#"},{"v":22,"t":"A kad su se skupili u Galileji, reče im Isus: “Sin Čovječji ima biti predan ljudima u ruke"},{"v":23,"t":"i ubit će ga, ali on će treći dan uskrsnuti.” I ožalostiše se silno."},{"v":24,"t":"Kad stigoše u Kafarnaum, pristupe Petru oni što ubiru dvodrahme pa mu rekoše: “Učitelj vaš ne plaća dvodrahme?”"},{"v":25,"t":"“Plaća”, odgovori. A kad on uđe u kuću, pretekne ga Isus: “Što ti se čini, Šimune? Kraljevi zemaljski od koga ubiru carinu ili porez? Od svojih sinova ili od tuđih?”"},{"v":26,"t":"Kad on odgovori: “Od tuđih!”, reče mu Isus: “Sinovi su, dakle, oslobođeni."},{"v":27,"t":"Ali da ih ne sablaznimo, pođi k moru, baci udicu i prvu ribu koja naiđe uzmi, otvori joj usta i naći ćeš stater. Uzmi ga pa im ga podaj za me i za se.”"}]},"18":{"fa":[{"v":1,"t":"در همان ساعت، شاگردان نزد عیسی آمده، گفتند: «چه کس در ملکوت آسمان بزرگتر است؟»"},{"v":2,"t":"آنگاه عیسی طفلی طلب نموده، در میان ایشان برپا داشت"},{"v":3,"t":"و گفت: «هرآینه به شما می‌گویم تا بازگشت نکنید و مثل طفل کوچک نشوید، هرگز داخل ملکوت آسمان نخواهید شد."},{"v":4,"t":"پس هر‌که مثل این بچه کوچک خود را فروتن سازد، همان در ملکوت آسمان بزرگتر است."},{"v":5,"t":"و کسی‌که چنین طفلی را به اسم من قبول کند، مرا پذیرفته است."},{"v":6,"t":"و هر‌که یکی ازاین صغار را که به من ایمان دارند، لغزش دهد او رابهتر می‌بود که سنگ آسیایی بر گردنش آویخته، در قعر دریا غرق می‌شد!"},{"v":7,"t":"وای بر این جهان به‌سبب لغزشها؛ زیرا که لابد است از وقوع لغزشها، لیکن وای بر کسی‌که سبب لغزش باشد."},{"v":8,"t":"پس اگر دستت یا پایت تو رابلغزاند، آن را قطع کرده، از خود دور انداز زیرا تورا بهتر است که لنگ یا شل داخل حیات شوی ازآنکه با دو دست یا دو پا در نار جاودانی افکنده شوی."},{"v":9,"t":"و اگر چشمت تو را لغزش دهد، آن را قلع کرده، از خود دور انداز زیرا تو را بهتر است بایک چشم وارد حیات شوی، از اینکه با دو چشم در آتش جهنم افکنده شوی."},{"v":10,"t":"زنهار یکی از این صغار را حقیر مشمارید، زیرا شما را می‌گویم که ملائکه ایشان دائم درآسمان روی پدر مرا که در آسمان است می‌بینند."},{"v":11,"t":"زیرا که پسر انسان آمده است تا گم شده رانجات‌بخشد."},{"v":12,"t":"شما چه گمان می‌برید، اگرکسی را صد گوسفند باشد و یکی از آنها گم شود، آیا آن نود و نه را به کوهسار نمی گذارد و به جستجوی آن گم شده نمی رود؟"},{"v":13,"t":"و اگر اتفاق آن را دریابد، هرآینه به شما می‌گویم بر آن یکی بیشتر شادی می‌کند از آن نود و نه که گم نشده‌اند."},{"v":14,"t":"همچنین اراده پدر شما که در آسمان است این نیست که یکی از این کوچکان هلاک گردد."},{"v":15,"t":"«و اگر برادرت به تو گناه کرده باشد، برو واو را میان خود و او در خلوت الزام کن. هرگاه سخن تو را گوش گرفت، برادر خود را دریافتی؛"},{"v":16,"t":"و اگر نشنود، یک یا دو نفر دیگر با خود بردار تااز زبان دو یا سه شاهد، هر سخنی ثابت شود."},{"v":17,"t":"واگر سخن ایشان را رد کند، به کلیسا بگو. و اگرکلیسا را قبول نکند، در نزد تو مثل خارجی یاباجگیر باشد."},{"v":18,"t":"هرآینه به شما می‌گویم آنچه برزمین بندید، در آسمان بسته شده باشد و آنچه برزمین گشایید، در آسمان گشوده شده باشد."},{"v":19,"t":"باز به شما می‌گویم هر گاه دو نفر از شما در زمین درباره هر‌چه که بخواهند متفق شوند، هرآینه ازجانب پدر من که در آسمان است برای ایشان کرده خواهد شد."},{"v":20,"t":"زیرا جایی که دو یا سه نفر به اسم من جمع شوند، آنجا درمیان ایشان حاضرم.»"},{"v":21,"t":"آنگاه پطرس نزد او آمده، گفت: «خداوندا، چند مرتبه برادرم به من خطا ورزد، می‌باید او راآمرزید؟ آیا تا هفت مرتبه؟»"},{"v":22,"t":"عیسی بدو گفت: «تو را نمی گویم تا هفت مرتبه، بلکه تا هفتاد هفت مرتبه!"},{"v":23,"t":"از آنجهت ملکوت آسمان پادشاهی راماند که با غلامان خود اراده محاسبه داشت."},{"v":24,"t":"وچون شروع به حساب نمود، شخصی را نزد اوآوردند که ده هزار قنطار به او بدهکار بود."},{"v":25,"t":"وچون چیزی نداشت که ادا نماید، آقایش امر کردکه او را با زن و فرزندان و تمام مایملک اوفروخته، طلب را وصول کنند."},{"v":26,"t":"پس آن غلام روبه زمین نهاده او را پرستش نمود و گفت: “ای آقامرا مهلت ده تا همه را به تو ادا کنم.”"},{"v":27,"t":"آنگاه آقای آن غلام بر وی ترحم نموده، او را رها کرد وقرض او را بخشید."},{"v":28,"t":"لیکن چون آن غلام بیرون رفت، یکی از همقطاران خود را یافت که از او صددینار طلب داشت. او را بگرفت و گلویش رافشرده، گفت: “طلب مرا ادا کن!”"},{"v":29,"t":"پس آن همقطار بر پایهای او افتاده، التماس نموده، گفت: “مرا مهلت ده تا همه را به تو رد کنم.”"},{"v":30,"t":"اما اوقبول نکرد بلکه رفته، او را در زندان انداخت تاقرض را ادا کند."},{"v":31,"t":"چون همقطاران وی این وقایع را دیدند، بسیار غمگین شده، رفتند و آنچه شده بود به آقای خود باز‌گفتند."},{"v":32,"t":"آنگاه مولایش او راطلبیده، گفت: “ای غلام شریر، آیا تمام آن قرض را محض خواهش تو به تو نبخشیدم؟"},{"v":33,"t":"پس آیاتو را نیز لازم نبود که بر همقطار خود رحم کنی چنانکه من بر تو رحم کردم؟”"},{"v":34,"t":"پس مولای او درغضب شده، او را به جلادان سپرد تا تمام قرض رابدهد."},{"v":35,"t":"به همینطور پدر آسمانی من نیز با شماعمل خواهد نمود، اگر هر یکی از شما برادر خودرا از دل نبخشد.»"}],"en":[{"v":1,"t":"In that hour the disciples came to Jesus, saying, “Who then is greatest in the Kingdom of Heaven?”"},{"v":2,"t":"Jesus called a little child to himself, and set him in the middle of them"},{"v":3,"t":"and said, “Most certainly I tell you, unless you turn and become as little children, you will in no way enter into the Kingdom of Heaven."},{"v":4,"t":"Whoever therefore humbles himself as this little child is the greatest in the Kingdom of Heaven."},{"v":5,"t":"Whoever receives one such little child in my name receives me,"},{"v":6,"t":"but whoever causes one of these little ones who believe in me to stumble, it would be better for him if a huge millstone were hung around his neck and that he were sunk in the depths of the sea."},{"v":7,"t":"“Woe to the world because of occasions of stumbling! For it must be that the occasions come, but woe to that person through whom the occasion comes!"},{"v":8,"t":"If your hand or your foot causes you to stumble, cut it off and cast it from you. It is better for you to enter into life maimed or crippled, rather than having two hands or two feet to be cast into the eternal fire."},{"v":9,"t":"If your eye causes you to stumble, pluck it out and cast it from you. It is better for you to enter into life with one eye, rather than having two eyes to be cast into the Gehenna of fire."},{"v":10,"t":"See that you don’t despise one of these little ones, for I tell you that in heaven their angels always see the face of my Father who is in heaven."},{"v":11,"t":"For the Son of Man came to save that which was lost."},{"v":12,"t":"“What do you think? If a man has one hundred sheep, and one of them goes astray, doesn’t he leave the ninety-nine, go to the mountains, and seek that which has gone astray?"},{"v":13,"t":"If he finds it, most certainly I tell you, he rejoices over it more than over the ninety-nine which have not gone astray."},{"v":14,"t":"Even so it is not the will of your Father who is in heaven that one of these little ones should perish."},{"v":15,"t":"“If your brother sins against you, go, show him his fault between you and him alone. If he listens to you, you have gained back your brother."},{"v":16,"t":"But if he doesn’t listen, take one or two more with you, that at the mouth of two or three witnesses every word may be established."},{"v":17,"t":"If he refuses to listen to them, tell it to the assembly. If he refuses to hear the assembly also, let him be to you as a Gentile or a tax collector."},{"v":18,"t":"Most certainly I tell you, whatever things you bind on earth will have been bound in heaven, and whatever things you release on earth will have been released in heaven."},{"v":19,"t":"Again, assuredly I tell you, that if two of you will agree on earth concerning anything that they will ask, it will be done for them by my Father who is in heaven."},{"v":20,"t":"For where two or three are gathered together in my name, there I am in the middle of them.”"},{"v":21,"t":"Then Peter came and said to him, “Lord, how often shall my brother sin against me, and I forgive him? Until seven times?”"},{"v":22,"t":"Jesus said to him, “I don’t tell you until seven times, but, until seventy times seven."},{"v":23,"t":"Therefore the Kingdom of Heaven is like a certain king who wanted to settle accounts with his servants."},{"v":24,"t":"When he had begun to settle, one was brought to him who owed him ten thousand talents."},{"v":25,"t":"But because he couldn’t pay, his lord commanded him to be sold, with his wife, his children, and all that he had, and payment to be made."},{"v":26,"t":"The servant therefore fell down and knelt before him, saying, ‘Lord, have patience with me, and I will repay you all!’"},{"v":27,"t":"The lord of that servant, being moved with compassion, released him and forgave him the debt."},{"v":28,"t":"“But that servant went out and found one of his fellow servants who owed him one hundred denarii, and he grabbed him and took him by the throat, saying, ‘Pay me what you owe!’"},{"v":29,"t":"“So his fellow servant fell down at his feet and begged him, saying, ‘Have patience with me, and I will repay you!’"},{"v":30,"t":"He would not, but went and cast him into prison until he should pay back that which was due."},{"v":31,"t":"So when his fellow servants saw what was done, they were exceedingly sorry, and came and told their lord all that was done."},{"v":32,"t":"Then his lord called him in and said to him, ‘You wicked servant! I forgave you all that debt because you begged me."},{"v":33,"t":"Shouldn’t you also have had mercy on your fellow servant, even as I had mercy on you?’"},{"v":34,"t":"His lord was angry, and delivered him to the tormentors until he should pay all that was due to him."},{"v":35,"t":"So my heavenly Father will also do to you, if you don’t each forgive your brother from your hearts for his misdeeds.”"}],"hr":[{"v":1,"t":"U onaj čas pristupe učenici Isusu pa ga zapitaju: “Tko je, dakle, najveći u kraljevstvu nebeskom?”"},{"v":2,"t":"On dozove dijete, postavi ga posred njih"},{"v":3,"t":"i reče: “Zaista, kažem vam, ako se ne obratite i ne postanete kao djeca, nećete ući u kraljevstvo nebesko."},{"v":4,"t":"Tko god se dakle ponizi kao ovo dijete, taj je najveći u kraljevstvu nebeskom."},{"v":5,"t":"I tko primi jedno ovakvo dijete u moje ime, mene prima.”"},{"v":6,"t":"“Onomu, naprotiv, tko bi sablaznio jednoga od ovih najmanjih što vjeruju u mene bilo bi bolje da mu se o vrat objesi mlinski kamen pa da potone u dubinu morsku.”"},{"v":7,"t":"“Jao svijetu od sablazni! Neizbježivo dolaze sablazni, ali jao čovjeku po kom dolazi sablazan."},{"v":8,"t":"Pa ako te ruka ili noga sablažnjava, odsijeci je i baci od sebe. Bolje ti je ući u život kljastu ili hromu, nego s obje ruke ili s obje noge biti bačen u oganj vječni."},{"v":9,"t":"I ako te oko sablažnjava, izvadi ga i baci od sebe. Bolje ti je jednooku u život ući, nego s oba oka biti bačen u pakao ognjeni.”"},{"v":10,"t":"“Pazite da ne prezrete ni jednoga od ovih najmanjih jer, kažem vam, anđeli njihovi na nebu uvijek gledaju lice Oca mojega, koji je na nebesima.”"},{"v":11,"t":"#"},{"v":12,"t":"“Što vam se čini? Ako neki čovjek imadne sto ovaca i jedna od njih zaluta, neće li on ostaviti onih devedeset i devet u gorama i poći u potragu za zalutalom?"},{"v":13,"t":"Posreći li mu se te je nađe, zaista, kažem vam, raduje se zbog nje više nego zbog onih devedeset i devet koje nisu zalutale."},{"v":14,"t":"Tako ni Otac vaš, koji je na nebesima, neće da propadne ni jedan od ovih malenih.”"},{"v":15,"t":"“Pogriješi li tvoj brat, idi i pokaraj ga nasamo."},{"v":16,"t":"Ako te posluša, stekao si brata. Ne posluša li te, uzmi sa sobom još jednoga ili dvojicu, neka na iskazu dvojice ili trojice svjedoka počiva svaka tvrdnja."},{"v":17,"t":"Ako ni njih ne posluša, reci Crkvi. Ako pak ni Crkve ne posluša, neka ti bude kao poganin i carinik.”"},{"v":18,"t":"“Zaista, kažem vam, što god svežete na zemlji, bit će svezano na nebu; i što god odriješite na zemlji, bit će odriješeno na nebu.”"},{"v":19,"t":"“Nadalje, kažem vam, ako dvojica od vas na zemlji jednodušno zaištu što mu drago, dat će im Otac moj, koji je na nebesima."},{"v":20,"t":"Jer gdje su dvojica ili trojica sabrana u moje ime, tu sam i ja među njima.”"},{"v":21,"t":"Tada pristupi k njemu Petar i reče: “Gospodine, koliko puta da oprostim bratu svomu ako se ogriješi o mene? Do sedam puta?”"},{"v":22,"t":"Kaže mu Isus: “Ne kažem ti do sedam puta, nego do sedamdeset puta sedam.”"},{"v":23,"t":"“Stoga je kraljevstvo nebesko kao kad kralj odluči urediti račune sa slugama."},{"v":24,"t":"Kad započe obračunavati, dovedoše mu jednoga koji mu dugovaše deset tisuća talenata."},{"v":25,"t":"Kako nije imao odakle vratiti, zapovjedi gospodar da se proda on, žena mu i djeca i sve što ima te se podmiri dug."},{"v":26,"t":"Nato sluga padne ničice preda nj govoreći: 'Strpljenja imaj sa mnom, i sve ću ti vratiti.'"},{"v":27,"t":"Gospodar se smilova tomu sluzi, otpusti ga i dug mu oprosti.”"},{"v":28,"t":"“A kad taj isti sluga izađe, naiđe na jednoga svoga druga koji mu dugovaše sto denara. Uhvati ga i stane ga daviti govoreći: 'Vrati što si dužan!'"},{"v":29,"t":"Drug padne preda nj i stane ga zaklinjati: 'Strpljenja imaj sa mnom i vratit ću ti.'"},{"v":30,"t":"Ali on ne htjede, nego ode i baci ga u tamnicu dok mu ne vrati duga.”"},{"v":31,"t":"“Kad njegovi drugovi vidješe što se dogodilo, silno ražalošćeni odoše i sve to dojaviše gospodaru."},{"v":32,"t":"Tada ga gospodar dozva i reče mu: 'Slugo opaki, sav sam ti onaj dug oprostio jer si me zamolio."},{"v":33,"t":"Nije li trebalo da se i ti smiluješ svome drugu, kao što sam se i ja tebi smilovao?'"},{"v":34,"t":"I gospodar ga, rasrđen, preda mučiteljima dok mu ne vrati svega duga."},{"v":35,"t":"Tako će i Otac moj nebeski učiniti s vama ako svatko od srca ne oprosti svomu bratu.”"}]},"19":{"fa":[{"v":1,"t":"و چون عیسی این سخنان را به اتمام رسانید، از جلیل روانه شده، به حدودیهودیه از آن طرف اردن آمد."},{"v":2,"t":"و گروهی بسیار ازعقب او آمدند و ایشان را در آنجا شفا بخشید."},{"v":3,"t":"پس فریسیان آمدند تا او را امتحان کنند وگفتند: «آیا جایز است مرد، زن خود را به هر علتی طلاق دهد؟»"},{"v":4,"t":"او در جواب ایشان گفت: «مگرنخوانده‌اید که خالق در ابتدا ایشان را مرد و زن آفرید،"},{"v":5,"t":"و گفت از این جهت مرد، پدر و مادرخود را رها کرده، به زن خویش بپیوندد و هر دویک تن خواهند شد؟"},{"v":6,"t":"بنابراین بعد از آن دونیستند بلکه یک تن هستند. پس آنچه را خداپیوست انسان جدا نسازد.»"},{"v":7,"t":"به وی گفتند: «پس از بهر‌چه موسی‌امر فرمود که زن را طلاقنامه دهند و جدا کنند؟»"},{"v":8,"t":"ایشان را گفت: «موسی به‌سبب سنگدلی شما، شما را اجازت داد که زنان خود را طلاق دهید. لیکن از ابتدا چنین نبود."},{"v":9,"t":"و به شما می‌گویم هر‌که زن خود را بغیر علت زناطلاق دهد و دیگری را نکاح کند، زانی است و هرکه زن مطلقه‌ای را نکاح کند، زنا کند.»"},{"v":10,"t":"شاگردانش بدو گفتند: «اگر حکم شوهر بازن چنین باشد، نکاح نکردن بهتر است!»"},{"v":11,"t":"ایشان را گفت: «تمامی خلق این کلام را نمی پذیرند، مگر به کسانی که عطا شده است."},{"v":12,"t":"زیرا که خصی‌ها می‌باشند که از شکم مادر چنین متولدشدند و خصی‌ها هستند که از مردم خصی شده‌اند و خصی‌ها می‌باشند که بجهت ملکوت خدا خود را خصی نموده‌اند. آنکه توانایی قبول دارد بپذیرد.»"},{"v":13,"t":"آنگاه چند بچه کوچک را نزد او آوردند تادستهای خود را بر ایشان نهاده، دعا کند. اماشاگردان، ایشان را نهیب دادند."},{"v":14,"t":"عیسی گفت: «بچه های کوچک را بگذارید و از آمدن نزد من، ایشان را منع مکنید، زیرا ملکوت آسمان از مثل اینها است.»"},{"v":15,"t":"و دستهای خود را بر ایشان گذارده از آن جا روانه شد."},{"v":16,"t":"ناگاه شخصی آمده، وی را گفت: «ای استادنیکو، چه عمل نیکو کنم تا حیات جاودانی یابم؟»"},{"v":17,"t":"وی را گفت: «از چه سبب مرا نیکو گفتی و حال آنکه کسی نیکو نیست، جز خدا فقط. لیکن اگربخواهی داخل حیات شوی، احکام را نگاه دار.»"},{"v":18,"t":"بدو گفت: «کدام احکام؟» عیسی گفت: «قتل مکن، زنا مکن، دزدی مکن، شهادت دروغ مده،"},{"v":19,"t":"و پدر و مادر خود را حرمت دار و همسایه خود را مثل نفس خود دوست دار.»"},{"v":20,"t":"جوان وی را گفت: «همه اینها را از طفولیت نگاه داشته‌ام. دیگر مرا چه ناقص است؟»"},{"v":21,"t":"عیسی بدو گفت: «اگر بخواهی کامل شوی، رفته مایملک خود رابفروش و به فقراء بده که در آسمان گنجی خواهی داشت؛ و آمده مرا متابعت نما.»"},{"v":22,"t":"چون جوان این سخن را شنید، دل تنگ شده، برفت زیرا که مال بسیار داشت."},{"v":23,"t":"عیسی به شاگردان خود گفت: «هرآینه به شما می‌گویم که شخص دولتمند به ملکوت آسمان به دشواری داخل می‌شود."},{"v":24,"t":"و باز شمارا می‌گویم که گذشتن شتر از سوراخ سوزن، آسانتر است از دخول شخص دولتمند درملکوت خدا.»"},{"v":25,"t":"شاگردان چون شنیدند، بغایت متحیر گشته، گفتند: «پس که می‌تواند نجات یابد؟»"},{"v":26,"t":"عیسی متوجه ایشان شده، گفت: «نزدانسان این محال است لیکن نزد خدا همه‌چیزممکن است.»"},{"v":27,"t":"آنگاه پطرس در جواب گفت: «اینک ما همه‌چیزها را ترک کرده، تو را متابعت می‌کنیم. پس ما را چه خواهد بود؟»"},{"v":28,"t":"«عیسی ایشان را گفت: «هرآینه به شما می‌گویم شما که مرا متابعت نموده‌اید، در معاد وقتی که پسر انسان بر کرسی جلال خود نشیند، شما نیز به دوازده کرسی نشسته، بر دوازده سبط اسرائیل داوری خواهید نمود."},{"v":29,"t":"و هر‌که بخاطر اسم من، خانه هایا برادران یا خواهران یا پدر یا مادر یا زن یافرزندان یا زمینها را ترک کرد، صد چندان خواهدیافت و وارث حیات جاودانی خواهد گشت."},{"v":30,"t":"لیکن بسا اولین که آخرین می‌گردند و آخرین، اولین!"}],"en":[{"v":1,"t":"When Jesus had finished these words, he departed from Galilee and came into the borders of Judea beyond the Jordan."},{"v":2,"t":"Great multitudes followed him, and he healed them there."},{"v":3,"t":"Pharisees came to him, testing him and saying, “Is it lawful for a man to divorce his wife for any reason?”"},{"v":4,"t":"He answered, “Haven’t you read that he who made them from the beginning made them male and female,"},{"v":5,"t":"and said, ‘For this cause a man shall leave his father and mother, and shall be joined to his wife; and the two shall become one flesh’?"},{"v":6,"t":"So that they are no more two, but one flesh. What therefore God has joined together, don’t let man tear apart.”"},{"v":7,"t":"They asked him, “Why then did Moses command us to give her a certificate of divorce and divorce her?”"},{"v":8,"t":"He said to them, “Moses, because of the hardness of your hearts, allowed you to divorce your wives, but from the beginning it has not been so."},{"v":9,"t":"I tell you that whoever divorces his wife, except for sexual immorality, and marries another, commits adultery; and he who marries her when she is divorced commits adultery.”"},{"v":10,"t":"His disciples said to him, “If this is the case of the man with his wife, it is not expedient to marry.”"},{"v":11,"t":"But he said to them, “Not all men can receive this saying, but those to whom it is given."},{"v":12,"t":"For there are eunuchs who were born that way from their mother’s womb, and there are eunuchs who were made eunuchs by men; and there are eunuchs who made themselves eunuchs for the Kingdom of Heaven’s sake. He who is able to receive it, let him receive it.”"},{"v":13,"t":"Then little children were brought to him that he should lay his hands on them and pray; and the disciples rebuked them."},{"v":14,"t":"But Jesus said, “Allow the little children, and don’t forbid them to come to me; for the Kingdom of Heaven belongs to ones like these.”"},{"v":15,"t":"He laid his hands on them, and departed from there."},{"v":16,"t":"Behold, one came to him and said, “Good teacher, what good thing shall I do, that I may have eternal life?”"},{"v":17,"t":"He said to him, “Why do you call me good? No one is good but one, that is, God. But if you want to enter into life, keep the commandments.”"},{"v":18,"t":"He said to him, “Which ones?” Jesus said, “‘You shall not murder.’ ‘You shall not commit adultery.’ ‘You shall not steal.’ ‘You shall not offer false testimony.’"},{"v":19,"t":"‘Honor your father and your mother.’ And, ‘You shall love your neighbor as yourself.’”"},{"v":20,"t":"The young man said to him, “All these things I have observed from my youth. What do I still lack?”"},{"v":21,"t":"Jesus said to him, “If you want to be perfect, go, sell what you have, and give to the poor, and you will have treasure in heaven; and come, follow me.”"},{"v":22,"t":"But when the young man heard this, he went away sad, for he was one who had great possessions."},{"v":23,"t":"Jesus said to his disciples, “Most certainly I say to you, a rich man will enter into the Kingdom of Heaven with difficulty."},{"v":24,"t":"Again I tell you, it is easier for a camel to go through a needle’s eye than for a rich man to enter into God’s Kingdom.”"},{"v":25,"t":"When the disciples heard it, they were exceedingly astonished, saying, “Who then can be saved?”"},{"v":26,"t":"Looking at them, Jesus said, “With men this is impossible, but with God all things are possible.”"},{"v":27,"t":"Then Peter answered, “Behold, we have left everything and followed you. What then will we have?”"},{"v":28,"t":"Jesus said to them, “Most certainly I tell you that you who have followed me, in the regeneration when the Son of Man will sit on the throne of his glory, you also will sit on twelve thrones, judging the twelve tribes of Israel."},{"v":29,"t":"Everyone who has left houses, or brothers, or sisters, or father, or mother, or wife, or children, or lands, for my name’s sake, will receive one hundred times, and will inherit eternal life."},{"v":30,"t":"But many will be last who are first, and first who are last."}],"hr":[{"v":1,"t":"Kad Isus završi ove besjede, ode iz Galileje i dođe u judejski kraj s onu stranu Jordana."},{"v":2,"t":"Za njim je išao silan svijet. Ondje ih izliječi."},{"v":3,"t":"Pristupe mu tada farizeji pa, da ga iskušaju, kažu: “Je li dopušteno otpustiti ženu s kojega god razloga?”"},{"v":4,"t":"On odgovori: “Zar niste čitali: Stvoritelj od početka muško i žensko stvori ih"},{"v":5,"t":"i reče: Stoga će čovjek ostaviti oca i majku da prione uza svoju ženu; i dvoje njih bit će jedno tijelo?"},{"v":6,"t":"Tako više nisu dvoje, nego jedno tijelo. Što, dakle, Bog združi, čovjek neka ne rastavlja.”"},{"v":7,"t":"Kažu mu: “Zašto onda Mojsije zapovjedi dati otpusno pismo i - otpustiti?”"},{"v":8,"t":"Odgovori im: “Zbog tvrdoće srca vašega dopusti vam Mojsije otpustiti žene, ali od početka ne bijaše tako."},{"v":9,"t":"A ja vam kažem: Tko otpusti svoju ženu - osim zbog bludništva - pa se oženi drugom, čini preljub.”"},{"v":10,"t":"Kažu mu učenici: “Ako je tako između muža i žene, bolje je ne ženiti se.”"},{"v":11,"t":"A on im reče: “Ne shvaćaju toga svi, nego samo oni kojima je dano."},{"v":12,"t":"Doista, ima za ženidbu nesposobnih koji se takvi iz utrobe materine rodiše. Ima nesposobnih koje ljudi onesposobiše. A ima nesposobnih koji sami sebe onesposobiše poradi kraljevstva nebeskoga. Tko može shvatiti, neka shvati.”"},{"v":13,"t":"Tada mu doniješe dječicu da na njih stavi ruke i pomoli se. A učenici im branili."},{"v":14,"t":"Nato će im Isus: “Pustite dječicu i ne priječite im k meni jer takvih je kraljevstvo nebesko!”"},{"v":15,"t":"I položi ruke na njih pa krene odande."},{"v":16,"t":"I gle, pristupi mu netko i reče: “Učitelju, koje mi je dobro činiti da imam život vječni?”"},{"v":17,"t":"A on mu reče: “Što me pitaš o dobrome? Jedan je samo dobar! Ali ako hoćeš u život ući, čuvaj zapovijedi.”"},{"v":18,"t":"Upita ga: “Koje?” A Isus reče: Ne ubij! Ne čini preljuba! Ne ukradi! Ne svjedoči lažno!"},{"v":19,"t":"Poštuj oca i majku! I ljubi svoga bližnjega kao sebe samoga!”"},{"v":20,"t":"Kaže mu mladić: “Sve sam to čuvao. Što mi još nedostaje?”"},{"v":21,"t":"Reče mu Isus: “Hoćeš li biti savršen, idi, prodaj što imaš i podaj siromasima pa ćeš imati blago na nebu. A onda dođi i idi za mnom.”"},{"v":22,"t":"Na tu riječ ode mladić žalostan jer imaše velik imetak."},{"v":23,"t":"A Isus reče svojim učenicima: “Zaista, kažem vas, teško će bogataš u kraljevstvo nebesko."},{"v":24,"t":"Ponovno vam velim: Lakše je devi kroz uši iglene nego bogatašu u kraljevstvo Božje.”"},{"v":25,"t":"Čuvši to, učenici se silno snebivahu govoreći: “Tko se onda može spasiti?”"},{"v":26,"t":"A Isus upre u njih pogled pa im reče: “Ljudima je to nemoguće, ali Bogu je sve moguće.”"},{"v":27,"t":"Tada Petar prihvati pa upita: “Evo, mi sve ostavismo i pođosmo za tobom. Što ćemo za to dobiti?”"},{"v":28,"t":"Reče im Isus: “Zaista, kažem vam, vi koji pođoste za mnom, o preporodu, kad Sin Čovječji sjedne na prijestolje svoje slave, i vi ćete sjediti na dvanaest prijestolja i suditi dvanaest plemena Izraelovih."},{"v":29,"t":"I tko god ostavi kuće, ili braću, ili sestre, ili oca, ili majku, ili ženu, ili djecu, ili polja poradi imena mojega, stostruko će primiti i život vječni baštiniti.”"},{"v":30,"t":"“A mnogi prvi bit će posljednji, i posljednji prvi.”"}]},"20":{"fa":[{"v":1,"t":"«زیرا ملکوت آسمان صاحب‌خانه‌ای را ماند که بامدادان بیرون رفت تا عمله بجهت تاکستان خود به مزد بگیرد."},{"v":2,"t":"پس با عمله، روزی یک دینار قرار داده، ایشان را به تاکستان خود فرستاد."},{"v":3,"t":"و قریب به ساعت سوم بیرون رفته، بعضی دیگر را در بازار بیکار ایستاده دید."},{"v":4,"t":"ایشان را نیز گفت: “شما هم به تاکستان بروید وآنچه حق شما است به شما می‌دهم.” پس رفتند."},{"v":5,"t":"باز قریب به ساعت ششم و نهم رفته، همچنین کرد."},{"v":6,"t":"و قریب به ساعت یازدهم رفته، چند نفردیگر بیکار ایستاده یافت. ایشان را گفت: “از بهرچه تمامی روز در اینجا بیکار ایستاده‌اید؟”"},{"v":7,"t":"گفتندش: “هیچ‌کس ما را به مزد نگرفت.” بدیشان گفت: “شما نیز به تاکستان بروید و حق خویش راخواهید یافت.”"},{"v":8,"t":"و چون وقت شام رسید، صاحب تاکستان به ناظر خود گفت: “مزدوران راطلبیده، از آخرین گرفته تا اولین مزد ایشان را اداکن.”"},{"v":9,"t":"پس یازده ساعتیان آمده، هر نفری دیناری یافتند."},{"v":10,"t":"و اولین آمده، گمان بردند که بیشترخواهند یافت. ولی ایشان نیز هر نفری دیناری یافتند."},{"v":11,"t":"اما چون گرفتند، به صاحب‌خانه شکایت نموده،"},{"v":12,"t":"گفتند که “این آخرین، یک ساعت کار کردند و ایشان را با ما که متحمل سختی و حرارت روز گردیده‌ایم مساوی ساخته‌ای؟”"},{"v":13,"t":"او در جواب یکی از ایشان گفت: “ای رفیق بر تو ظلمی نکردم. مگر به دیناری با من قرار ندادی؟"},{"v":14,"t":"حق خود را گرفته برو. می‌خواهم بدین آخری مثل تو دهم."},{"v":15,"t":"آیا مرا جایز نیست که از مال خود آنچه خواهم بکنم؟ مگر چشم توبد است از آن رو که من نیکو هستم؟”"},{"v":16,"t":"بنابراین اولین آخرین و آخرین اولین خواهند شد، زیراخوانده‌شدگان بسیارند و برگزیدگان کم.»"},{"v":17,"t":"و چون عیسی به اورشلیم می‌رفت، دوازده شاگرد خود را در اثنای راه به خلوت طلبیده بدیشان گفت:"},{"v":18,"t":"«اینک به سوی اورشلیم می‌رویم و پسر انسان به روسای کهنه و کاتبان تسلیم کرده خواهد شد و حکم قتل او را خواهندداد،"},{"v":19,"t":"و او را به امت‌ها خواهند سپرد تا او رااستهزا کنند و تازیانه زنند و مصلوب نمایند و درروز سوم خواهد برخاست.»"},{"v":20,"t":"آنگاه مادر دو پسر زبدی با پسران خود نزدوی آمده و پرستش نموده، از او چیزی درخواست کرد."},{"v":21,"t":"بدو گفت: «چه خواهش داری؟» گفت: «بفرما تا این دو پسر من در ملکوت تو، یکی بر دست راست و دیگری بر دست چپ تو بنشینند.»"},{"v":22,"t":"عیسی در جواب گفت: «نمی دانید چه می‌خواهید. آیا می‌توانید از آن کاسه‌ای که من می‌نوشم، بنوشید و تعمیدی را که من می‌یابم، بیابید؟» بدو گفتند: «می‌توانیم.»"},{"v":23,"t":"ایشان را گفت: «البته از کاسه من خواهیدنوشید و تعمیدی را که من می‌یابم، خواهید یافت. لیکن نشستن به‌دست راست و چپ من، از آن من نیست که بدهم، مگر به کسانی که از جانب پدرم برای ایشان مهیا شده است.»"},{"v":24,"t":"اما چون آن ده شاگرد شنیدند، بر آن دوبرادر به دل رنجیدند."},{"v":25,"t":"عیسی ایشان را پیش طلبیده، گفت: «آگاه هستید که حکام امت‌ها برایشان سروری می‌کنند و روسا بر ایشان مسلطند."},{"v":26,"t":"لیکن در میان شما چنین نخواهد بود، بلکه هرکه در میان شما می‌خواهد بزرگ گردد، خادم شماباشد."},{"v":27,"t":"و هر‌که می‌خواهد در میان شما مقدم بود، غلام شما باشد."},{"v":28,"t":"چنانکه پسر انسان نیامدتا مخدوم شود بلکه تا خدمت کند و جان خود رادر راه بسیاری فدا سازد.»"},{"v":29,"t":"و هنگامی که از اریحا بیرون می‌رفتند، گروهی بسیار از عقب او می‌آمدند."},{"v":30,"t":"که ناگاه دومرد کور کنار راه نشسته، چون شنیدند که عیسی در گذر است، فریاد کرده، گفتند: «خداوندا، پسرداودا، بر ما ترحم کن!»"},{"v":31,"t":"و هر‌چند خلق ایشان را نهیب می‌دادند که خاموش شوند، بیشتر فریادکنان می‌گفتند: «خداوندا، پسر داودا، بر ما ترحم فرما!»"},{"v":32,"t":"پس عیسی ایستاده، به آواز بلند گفت: «چه می‌خواهید برای شما کنم؟»"},{"v":33,"t":"به وی گفتند: «خداوندا، اینکه چشمان ما باز‌گردد!»"},{"v":34,"t":"پس عیسی ترحم نموده، چشمان ایشان را لمس نمودکه در ساعت بینا گشته، از عقب او روانه شدند."}],"en":[{"v":1,"t":"“For the Kingdom of Heaven is like a man who was the master of a household, who went out early in the morning to hire laborers for his vineyard."},{"v":2,"t":"When he had agreed with the laborers for a denarius a day, he sent them into his vineyard."},{"v":3,"t":"He went out about the third hour, and saw others standing idle in the marketplace."},{"v":4,"t":"He said to them, ‘You also go into the vineyard, and whatever is right I will give you.’ So they went their way."},{"v":5,"t":"Again he went out about the sixth and the ninth hour, and did likewise."},{"v":6,"t":"About the eleventh hour he went out and found others standing idle. He said to them, ‘Why do you stand here all day idle?’"},{"v":7,"t":"“They said to him, ‘Because no one has hired us.’ “He said to them, ‘You also go into the vineyard, and you will receive whatever is right.’"},{"v":8,"t":"“When evening had come, the lord of the vineyard said to his manager, ‘Call the laborers and pay them their wages, beginning from the last to the first.’"},{"v":9,"t":"“When those who were hired at about the eleventh hour came, they each received a denarius."},{"v":10,"t":"When the first came, they supposed that they would receive more; and they likewise each received a denarius."},{"v":11,"t":"When they received it, they murmured against the master of the household,"},{"v":12,"t":"saying, ‘These last have spent one hour, and you have made them equal to us who have borne the burden of the day and the scorching heat!’"},{"v":13,"t":"“But he answered one of them, ‘Friend, I am doing you no wrong. Didn’t you agree with me for a denarius?"},{"v":14,"t":"Take that which is yours, and go your way. It is my desire to give to this last just as much as to you."},{"v":15,"t":"Isn’t it lawful for me to do what I want to with what I own? Or is your eye evil, because I am good?’"},{"v":16,"t":"So the last will be first, and the first last. For many are called, but few are chosen.”"},{"v":17,"t":"As Jesus was going up to Jerusalem, he took the twelve disciples aside, and on the way he said to them,"},{"v":18,"t":"“Behold, we are going up to Jerusalem, and the Son of Man will be delivered to the chief priests and scribes, and they will condemn him to death,"},{"v":19,"t":"and will hand him over to the Gentiles to mock, to scourge, and to crucify; and the third day he will be raised up.”"},{"v":20,"t":"Then the mother of the sons of Zebedee came to him with her sons, kneeling and asking a certain thing of him."},{"v":21,"t":"He said to her, “What do you want?” She said to him, “Command that these, my two sons, may sit, one on your right hand and one on your left hand, in your Kingdom.”"},{"v":22,"t":"But Jesus answered, “You don’t know what you are asking. Are you able to drink the cup that I am about to drink, and be baptized with the baptism that I am baptized with?” They said to him, “We are able.”"},{"v":23,"t":"He said to them, “You will indeed drink my cup, and be baptized with the baptism that I am baptized with; but to sit on my right hand and on my left hand is not mine to give, but it is for whom it has been prepared by my Father.”"},{"v":24,"t":"When the ten heard it, they were indignant with the two brothers."},{"v":25,"t":"But Jesus summoned them, and said, “You know that the rulers of the nations lord it over them, and their great ones exercise authority over them."},{"v":26,"t":"It shall not be so among you; but whoever desires to become great among you shall be your servant."},{"v":27,"t":"Whoever desires to be first among you shall be your bondservant,"},{"v":28,"t":"even as the Son of Man came not to be served, but to serve, and to give his life as a ransom for many.”"},{"v":29,"t":"As they went out from Jericho, a great multitude followed him."},{"v":30,"t":"Behold, two blind men sitting by the road, when they heard that Jesus was passing by, cried out, “Lord, have mercy on us, you son of David!”"},{"v":31,"t":"The multitude rebuked them, telling them that they should be quiet, but they cried out even more, “Lord, have mercy on us, you son of David!”"},{"v":32,"t":"Jesus stood still and called them, and asked, “What do you want me to do for you?”"},{"v":33,"t":"They told him, “Lord, that our eyes may be opened.”"},{"v":34,"t":"Jesus, being moved with compassion, touched their eyes; and immediately their eyes received their sight, and they followed him."}],"hr":[{"v":1,"t":"“Kraljevstvo je nebesko kao kad domaćin rano ujutro izađe najmiti radnike u svoj vinograd."},{"v":2,"t":"Pogodi se s radnicima po denar na dan i pošalje ih u svoj vinograd."},{"v":3,"t":"Izađe i o trećoj uri i vidje druge gdje stoje na trgu besposleni"},{"v":4,"t":"pa i njima reče: 'Idite i vi u moj vinograd pa što bude pravo, dat ću vam.'"},{"v":5,"t":"I oni odoše. Izađe opet o šestoj i devetoj uri te učini isto tako."},{"v":6,"t":"A kad izađe o jedanaestoj uri, nađe druge gdje stoje i reče im: 'Zašto ovdje stojite vazdan besposleni?'"},{"v":7,"t":"Kažu mu: 'Jer nas nitko ne najmi.' Reče im: 'Idite i vi u vinograd.'”"},{"v":8,"t":"“Uvečer kaže gospodar vinograda svojemu upravitelju: 'Pozovi radnike i podaj im plaću počevši od posljednjih pa sve do prvih.'"},{"v":9,"t":"Dođu tako oni od jedanaeste ure i prime po denar."},{"v":10,"t":"Pa kada dođu oni prvi, pomisle da će primiti više, ali i oni prime po denar."},{"v":11,"t":"A kad primiše, počeše mrmljati protiv domaćina:"},{"v":12,"t":"'Ovi posljednji jednu su uru radili i izjednačio si ih s nama, koji smo podnosili svu tegobu dana i žegu.'”"},{"v":13,"t":"“Nato on odgovori jednomu od njih: 'Prijatelju, ne činim ti krivo. Nisi li se pogodio sa mnom po denar?"},{"v":14,"t":"Uzmi svoje pa idi. A ja hoću i ovomu posljednjemu dati kao i tebi."},{"v":15,"t":"Nije li mi slobodno činiti sa svojim što hoću? Ili zar je oko tvoje zlo što sam ja dobar?'”"},{"v":16,"t":"“Tako će posljednji biti prvi, a prvi posljednji.”"},{"v":17,"t":"Dok je Isus uzlazio u Jeruzalem, uze dvanaestoricu nasamo te im putem reče:"},{"v":18,"t":"“Evo, uzlazimo u Jeruzalem i Sin Čovječji bit će predan glavarima svećeničkim i pismoznancima. Osudit će ga na smrt"},{"v":19,"t":"i predati poganima da ga izrugaju, izbičuju i razapnu, ali on će treći dan uskrsnuti.”"},{"v":20,"t":"Tada mu pristupi mati sinova Zebedejevih zajedno sa sinovima, pade ničice da od njega nešto zaište."},{"v":21,"t":"A on će joj: “Što želiš?” Kaže mu: “Reci da ova moja dva sina u tvome kraljevstvu sjednu uza te, jedan tebi zdesna, drugi slijeva.”"},{"v":22,"t":"Isus odgovori: “Ne znate što ištete. Možete li piti čašu koju ću ja piti?” Kažu mu: “Možemo!”"},{"v":23,"t":"A on im reče: “Čašu ćete moju doduše piti, ali sjesti meni zdesna ili slijeva - to nisam ja vlastan dati, to je onih kojima je pripravio moj Otac.”"},{"v":24,"t":"Kada su to čula ostala desetorica, razgnjeve se na dva brata."},{"v":25,"t":"Zato ih Isus dozva i reče: “Znate da vladari gospoduju svojim narodima i velikaši njihovi drže ih pod vlašću."},{"v":26,"t":"Neće tako biti među vama! Naprotiv, tko hoće da među vama bude najveći, neka vam bude poslužitelj."},{"v":27,"t":"I tko god hoće da među vama bude prvi, neka vam bude sluga.”"},{"v":28,"t":"“Tako i Sin Čovječji nije došao da bude služen, nego da služi i život svoj dade kao otkupninu za mnoge.”"},{"v":29,"t":"Kad su izlazili iz Jerihona, pođe za njim silan svijet."},{"v":30,"t":"I gle, dva slijepca sjeđahu kraj puta. Čuvši da Isus prolazi, povikaše: “Gospodine, smiluj nam se, Sine Davidov!”"},{"v":31,"t":"Mnoštvo ih ušutkivalo, ali oni još jače viknuše: “Gospodine, smiluj nam se, Sine Davidov!”"},{"v":32,"t":"Isus se zaustavi, dozove ih i reče: “Što hoćete da vam učinim?”"},{"v":33,"t":"Kažu mu: “Gospodine, da nam se otvore oči.”"},{"v":34,"t":"Isus se ganut dotače njihovim očiju i oni odmah progledaše. I pođoše za njim."}]},"21":{"fa":[{"v":1,"t":"و چون نزدیک به اورشلیم رسیده، واردبیت‌فاجی نزد کوه زیتون شدند. آنگاه عیسی دو نفر از شاگردان خود را فرستاده،"},{"v":2,"t":"بدیشان گفت: «در این قریه‌ای که پیش روی شمااست بروید و در حال، الاغی با کره‌اش بسته خواهید یافت. آنها را باز کرده، نزد من آورید."},{"v":3,"t":"وهرگاه کسی به شما سخنی گوید، بگویید خداوندبدینها احتیاج دارد که فی الفور آنها را خواهدفرستاد.»"},{"v":4,"t":"و این همه واقع شد تا سخنی که نبی گفته است تمام شود"},{"v":5,"t":"که «دختر صهیون را گوییداینک پادشاه تو نزد تو می‌آید با فروتنی و سواره بر حمار و بر کره الاغ.»"},{"v":6,"t":"پس شاگردان رفته، آنچه عیسی بدیشان امر فرمود، بعمل آوردند"},{"v":7,"t":"و الاغ را با کره آورده، رخت خود را بر آنها انداختند واو بر آنها سوار شد."},{"v":8,"t":"و گروهی بسیار، رختهای خود را در راه گسترانیدند و جمعی از درختان شاخه‌ها بریده، در راه می‌گستردند."},{"v":9,"t":"و جمعی ازپیش و پس او رفته، فریادکنان می‌گفتند: «هوشیعانا پسر داودا، مبارک باد کسی‌که به اسم خداوند می‌آید! هوشیعانا در اعلی علیین!»"},{"v":10,"t":"وچون وارد اورشلیم شد، تمام شهر به آشوب آمده، می‌گفتند: «این کیست؟»"},{"v":11,"t":"آن گروه گفتند: «این است عیسی نبی از ناصره جلیل.»"},{"v":12,"t":"پس عیسی داخل هیکل خدا گشته، جمیع کسانی را که در هیکل خرید و فروش می‌کردند، بیرون نمود و تختهای صرافان و کرسیهای کبوترفروشان را واژگون ساخت."},{"v":13,"t":"و ایشان را گفت: «مکتوب است که خانه من خانه دعا نامیده می‌شود. لیکن شما مغاره دزدانش ساخته‌اید.»"},{"v":14,"t":"و کوران و شلان در هیکل، نزد او آمدند وایشان را شفا بخشید."},{"v":15,"t":"اما روسای کهنه و کاتبان چون عجایبی که از او صادر می‌گشت و کودکان را که در هیکل فریاد برآورده، «هوشیعانا پسر داودا» می‌گفتنددیدند، غضبناک گشته،"},{"v":16,"t":"به وی گفتند: «نمی شنوی آنچه اینها می‌گویند؟» عیسی بدیشان گفت: «بلی مگر نخوانده‌اید این که از دهان کودکان و شیرخوارگان حمد را مهیا ساختی؟»"},{"v":17,"t":"پس ایشان را واگذارده، از شهر بسوی بیت عنیارفته، در آنجا شب را بسر برد."},{"v":18,"t":"بامدادان چون به شهر مراجعت می‌کرد، گرسنه شد."},{"v":19,"t":"و در کناره راه یک درخت انجیر دیده، نزد آن آمد و جز برگ بر آن هیچ نیافت. پس آن را گفت: «از این به بعد میوه تا به ابد بر تونشود!» که در ساعت درخت انجیر خشکید!"},{"v":20,"t":"چون شاگردان´ این را دیدند، متعجب شده، گفتند: «چه بسیار زود درخت انحیر خشک شده است!»"},{"v":21,"t":"عیسی در جواب ایشان گفت: «هرآینه به شما می‌گویم اگر ایمان می‌داشتید و شک نمی نمودید، نه همین را که به درخت انجیر شدمی کردید، بلکه هر گاه بدین کوه می‌گفتید “منتقل شده به دریا افکنده شو” چنین می‌شد."},{"v":22,"t":"و هرآنچه با‌ایمان به دعا طلب کنید، خواهید یافت.»"},{"v":23,"t":"و چون به هیکل درآمده، تعلیم می‌داد، روسای کهنه و مشایخ قوم نزد او آمده، گفتند: «به چه قدرت این اعمال را می‌نمایی و کیست که این قدرت را به تو داده است؟»"},{"v":24,"t":"عیسی در جواب ایشان گفت: «من نیز از شما سخنی می‌پرسم. اگرآن را به من گویید، من هم به شما گویم که این اعمال را به چه قدرت می‌نمایم:"},{"v":25,"t":"تعمید یحیی از کجا بود؟ از آسمان یا از انسان؟» ایشان با خودتفکر کرده، گفتند که «اگر گوییم از آسمان بود، هرآینه گوید پس چرا به وی ایمان نیاوردید."},{"v":26,"t":"واگر گوییم از انسان بود، از مردم می‌ترسیم زیراهمه یحیی را نبی می‌دانند.»"},{"v":27,"t":"پس در جواب عیسی گفتند: «نمی دانیم.» بدیشان گفت: «من هم شما را نمی گویم که به چه قدرت این کارها رامی کنم."},{"v":28,"t":"لیکن چه گمان دارید؟ شخصی را دو پسربود. نزد نخستین آمده، گفت: “ای فرزند امروز به تاکستان من رفته، به‌کار مشغول شو.”"},{"v":29,"t":"درجواب گفت: “نخواهم رفت.” اما بعد پشیمان گشته، برفت."},{"v":30,"t":"و به دومین نیز همچنین گفت. اودر جواب گفت: “ای آقا من می‌روم.” ولی نرفت."},{"v":31,"t":"کدام‌یک از این دو خواهش پدر را به‌جاآورد؟» گفتند: «اولی.» عیسی بدیشان گفت: «هرآینه به شما می‌گویم که باجگیران و فاحشه هاقبل از شما داخل ملکوت خدا می‌گردند،"},{"v":32,"t":"زانرو که یحیی از راه عدالت نزد شما آمد وبدو ایمان نیاوردید، اما باجگیران و فاحشه‌ها بدوایمان آوردند و شما چون دیدید آخر هم پشیمان نشدید تا بدو ایمان آورید."},{"v":33,"t":"و مثلی دیگر بشنوید: صاحب‌خانه‌ای بودکه تاکستانی غرس نموده، خطیره‌ای گردش کشید و چرخشتی در آن کند و برجی بنا نمود. پس آن را به دهقانان سپرده، عازم سفر شد."},{"v":34,"t":"وچون موسم میوه نزدیک شد، غلامان خود را نزددهقانان فرستاد تا میوه های او را بردارند."},{"v":35,"t":"امادهقانان غلامانش را گرفته، بعضی را زدند وبعضی را کشتند و بعضی را سنگسار نمودند."},{"v":36,"t":"باز غلامان دیگر، بیشتر از اولین فرستاده، بدیشان نیز به همانطور سلوک نمودند."},{"v":37,"t":"بالاخره پسر خود را نزد ایشان فرستاده، گفت: “پسر مرا حرمت خواهند داشت.”"},{"v":38,"t":"اما دهقانان چون پسررا دیدند با خود گفتند: “این وارث است. بیایید اورا بکشیم و میراثش را ببریم.”"},{"v":39,"t":"آنگاه او راگرفته، بیرون تاکستان افکنده، کشتند."},{"v":40,"t":"پس چون مالک تاکستان آید، به آن دهقانان چه خواهد کرد؟»"},{"v":41,"t":"گفتند: «البته آن بدکاران را به سختی هلاک خواهد کرد و باغ را به باغبانان دیگرخواهد سپرد که میوه هایش را در موسم بدودهند.»"},{"v":42,"t":"عیسی بدیشان گفت: «مگر در کتب هرگزنخوانده‌اید این که سنگی را که معمارانش ردنمودند، همان سر زاویه شده است. این از جانب خداوند آمد و در نظر ما عجیب است."},{"v":43,"t":"از این جهت شما را می‌گویم که ملکوت خدا از شماگرفته شده، به امتی که میوه‌اش را بیاورند، عطاخواهد شد."},{"v":44,"t":"و هر‌که بر آن سنگ افتد، منکسرشود و اگر آن بر کسی افتد، نرمش سازد.»"},{"v":45,"t":"وچون روسای کهنه و فریسیان مثلهایش راشنیدند، دریافتند که درباره ایشان می‌گوید."},{"v":46,"t":"وچون خواستند او را گرفتار کنند، از مردم ترسیدند زیرا که او را نبی می‌دانستند."}],"en":[{"v":1,"t":"When they came near to Jerusalem and came to Bethsphage, to the Mount of Olives, then Jesus sent two disciples,"},{"v":2,"t":"saying to them, “Go into the village that is opposite you, and immediately you will find a donkey tied, and a colt with her. Untie them and bring them to me."},{"v":3,"t":"If anyone says anything to you, you shall say, ‘The Lord needs them,’ and immediately he will send them.”"},{"v":4,"t":"All this was done that it might be fulfilled which was spoken through the prophet, saying,"},{"v":5,"t":"“Tell the daughter of Zion, behold, your King comes to you, humble, and riding on a donkey, on a colt, the foal of a donkey.”"},{"v":6,"t":"The disciples went and did just as Jesus commanded them,"},{"v":7,"t":"and brought the donkey and the colt and laid their clothes on them; and he sat on them."},{"v":8,"t":"A very great multitude spread their clothes on the road. Others cut branches from the trees and spread them on the road."},{"v":9,"t":"The multitudes who went in front of him, and those who followed, kept shouting, “Hosanna to the son of David! Blessed is he who comes in the name of the Lord! Hosanna in the highest!”"},{"v":10,"t":"When he had come into Jerusalem, all the city was stirred up, saying, “Who is this?”"},{"v":11,"t":"The multitudes said, “This is the prophet, Jesus, from Nazareth of Galilee.”"},{"v":12,"t":"Jesus entered into the temple of God and drove out all of those who sold and bought in the temple, and overthrew the money changers’ tables and the seats of those who sold the doves."},{"v":13,"t":"He said to them, “It is written, ‘My house shall be called a house of prayer,’ but you have made it a den of robbers!”"},{"v":14,"t":"The lame and the blind came to him in the temple, and he healed them."},{"v":15,"t":"But when the chief priests and the scribes saw the wonderful things that he did, and the children who were crying in the temple and saying, “Hosanna to the son of David!” they were indignant,"},{"v":16,"t":"and said to him, “Do you hear what these are saying?” Jesus said to them, “Yes. Did you never read, ‘Out of the mouth of children and nursing babies, you have perfected praise’?”"},{"v":17,"t":"He left them and went out of the city to Bethany, and camped there."},{"v":18,"t":"Now in the morning, as he returned to the city, he was hungry."},{"v":19,"t":"Seeing a fig tree by the road, he came to it and found nothing on it but leaves. He said to it, “Let there be no fruit from you forever!” Immediately the fig tree withered away."},{"v":20,"t":"When the disciples saw it, they marveled, saying, “How did the fig tree immediately wither away?”"},{"v":21,"t":"Jesus answered them, “Most certainly I tell you, if you have faith and don’t doubt, you will not only do what was done to the fig tree, but even if you told this mountain, ‘Be taken up and cast into the sea,’ it would be done."},{"v":22,"t":"All things, whatever you ask in prayer, believing, you will receive.”"},{"v":23,"t":"When he had come into the temple, the chief priests and the elders of the people came to him as he was teaching, and said, “By what authority do you do these things? Who gave you this authority?”"},{"v":24,"t":"Jesus answered them, “I also will ask you one question, which if you tell me, I likewise will tell you by what authority I do these things."},{"v":25,"t":"The baptism of John, where was it from? From heaven or from men?” They reasoned with themselves, saying, “If we say, ‘From heaven,’ he will ask us, ‘Why then did you not believe him?’"},{"v":26,"t":"But if we say, ‘From men,’ we fear the multitude, for all hold John as a prophet.”"},{"v":27,"t":"They answered Jesus, and said, “We don’t know.” He also said to them, “Neither will I tell you by what authority I do these things."},{"v":28,"t":"But what do you think? A man had two sons, and he came to the first, and said, ‘Son, go work today in my vineyard.’"},{"v":29,"t":"He answered, ‘I will not,’ but afterward he changed his mind, and went."},{"v":30,"t":"He came to the second, and said the same thing. He answered, ‘I’m going, sir,’ but he didn’t go."},{"v":31,"t":"Which of the two did the will of his father?” They said to him, “The first.” Jesus said to them, “Most certainly I tell you that the tax collectors and the prostitutes are entering into God’s Kingdom before you."},{"v":32,"t":"For John came to you in the way of righteousness, and you didn’t believe him; but the tax collectors and the prostitutes believed him. When you saw it, you didn’t even repent afterward, that you might believe him."},{"v":33,"t":"“Hear another parable. There was a man who was a master of a household who planted a vineyard, set a hedge about it, dug a wine press in it, built a tower, leased it out to farmers, and went into another country."},{"v":34,"t":"When the season for the fruit came near, he sent his servants to the farmers to receive his fruit."},{"v":35,"t":"The farmers took his servants, beat one, killed another, and stoned another."},{"v":36,"t":"Again, he sent other servants more than the first; and they treated them the same way."},{"v":37,"t":"But afterward he sent to them his son, saying, ‘They will respect my son.’"},{"v":38,"t":"But the farmers, when they saw the son, said among themselves, ‘This is the heir. Come, let’s kill him and seize his inheritance.’"},{"v":39,"t":"So they took him and threw him out of the vineyard, then killed him."},{"v":40,"t":"When therefore the lord of the vineyard comes, what will he do to those farmers?”"},{"v":41,"t":"They told him, “He will miserably destroy those miserable men, and will lease out the vineyard to other farmers who will give him the fruit in its season.”"},{"v":42,"t":"Jesus said to them, “Did you never read in the Scriptures, ‘The stone which the builders rejected was made the head of the corner. This was from the Lord. It is marvelous in our eyes’?"},{"v":43,"t":"“Therefore I tell you, God’s Kingdom will be taken away from you and will be given to a nation producing its fruit."},{"v":44,"t":"He who falls on this stone will be broken to pieces, but on whomever it will fall, it will scatter him as dust.”"},{"v":45,"t":"When the chief priests and the Pharisees heard his parables, they perceived that he spoke about them."},{"v":46,"t":"When they sought to seize him, they feared the multitudes, because they considered him to be a prophet."}],"hr":[{"v":1,"t":"Kad se približiše Jeruzalemu te dođoše u Betfagu, na Maslinskoj gori, posla Isus dvojicu učenika"},{"v":2,"t":"govoreći: “Pođite u selo pred vama i odmah ćete naći privezanu magaricu i uz nju magare. Odriješite ih i dovedite k meni."},{"v":3,"t":"Ako vam tko što rekne, recite: 'Gospodinu trebaju', i odmah će ih pustiti.”"},{"v":4,"t":"To se dogodi da se ispuni što je rečeno po proroku:"},{"v":5,"t":"Recite kćeri Sionskoj: Evo kralj ti tvoj dolazi, krotak, jašuć na magarcu, na magaretu, mladetu magaričinu."},{"v":6,"t":"Učenici odu i učine kako im naredi Isus."},{"v":7,"t":"Dovedu magaricu i magare te stave na njih haljine i Isus uzjaha na njih."},{"v":8,"t":"Silan svijet prostrije svoje haljine po putu, a drugi rezahu grane sa stabala i sterahu ih po putu."},{"v":9,"t":"Mnoštvo pak pred njim i za njim klicaše: “Hosana Sinu Davidovu! Blagoslovljen Onaj koji dolazi u ime Gospodnje! Hosana u visinama!”"},{"v":10,"t":"Kad uđe u Jeruzalem, uskomešao se sav grad i govorio: “Tko je ovaj?”"},{"v":11,"t":"A mnoštvo odgovaraše: “To je Prorok, Isus iz Nazareta galilejskoga.”"},{"v":12,"t":"Isus uđe u Hram i izagna sve koji su prodavali i kupovali u Hramu. Mjenjačima isprevrta stolove i prodavačima golubova klupe."},{"v":13,"t":"Kaže im: “Pisamo je: Dom će se moj zvati Dom molitve, a vi od njega činite pećinu razbojničku.”"},{"v":14,"t":"U Hramu mu priđoše slijepi i hromi i on ih ozdravi."},{"v":15,"t":"A kad glavari svećenički i pismoznanci vidješe čudesa koja učini i djecu što viču Hramom: “Hosana Sinu Davidovu!”, gnjevni"},{"v":16,"t":"mu rekoše: “Čuješ li što ovi govore?” Kaže im Isus: “Da! A niste li čitali: Iz usta djece i dojenčadi sebi si pripravio hvalu?”"},{"v":17,"t":"On ih ostavi, pođe iz grada u Betaniju te ondje prenoći."},{"v":18,"t":"Ujutro se vraćao u grad i ogladnje."},{"v":19,"t":"Ugleda smokvu kraj puta i priđe k njoj, ali ne nađe na njoj ništa osim lišća pa joj kaže: “Ne bilo više ploda s tebe dovijeka!” I smokva umah usahnu."},{"v":20,"t":"Vidjevši to, učenici se začude: “Kako umah smokva usahnu!”"},{"v":21,"t":"Isus im odvrati: “Zaista, kažem vam, ako budete imali vjeru i ne posumnjate, činit ćete ne samo ovo sa smokvom, nego - reknete li i ovoj gori: 'Digni se i baci u more!', bit će tako."},{"v":22,"t":"I sve što zaištete u molitvi vjerujući, primit ćete.”"},{"v":23,"t":"I uđe u Hram. Dok je naučavao, pristupiše mu glavari svećenički i starješine narodne te ga upitaše: “Kojom vlašću to činiš? Tko ti dade tu vlast?”"},{"v":24,"t":"Isus im odgovori: “I ja ću vas jedno upitati. Ako mi na to odgovorite, ja ću vama kazati kojom vlašću ovo činim."},{"v":25,"t":"Krst Ivanov odakle li bijaše? Od Neba ili od ljudi?” A oni umovahu među sobom: “Reknemo li 'Od Neba', odvratit će nam: 'Zašto mu, dakle, ne povjerovaste?'"},{"v":26,"t":"A reknemo li 'Od ljudi', strah nas je mnoštva. Ta svi Ivana smatraju prorokom.”"},{"v":27,"t":"Zato odgovore Isusu: “Ne znamo.” I on njima reče: “Ni ja vama neću kazati kojom vlašću ovo činim.”"},{"v":28,"t":"“A što vam se čini? Čovjek neki imao dva sina. Priđe prvomu i reče: 'Sinko, hajde danas na posao u vinograd!'"},{"v":29,"t":"On odgovori: 'Neću!' No poslije se predomisli i ode."},{"v":30,"t":"Priđe i drugomu pa mu reče isto tako. A on odgovori: 'Evo me, gospodaru!' i ne ode."},{"v":31,"t":"Koji od te dvojice izvrši volju očevu?” Kažu: “Onaj prvi.” Nato će im Isus: “Zaista, kažem vam, carinici i bludnice pretekoše vas u kraljevstvo Božje!"},{"v":32,"t":"Doista, Ivan dođe k vama putom pravednosti i vi mu ne povjerovaste, a carinici mu i bludnice povjerovaše. Vi pak, makar to vidjeste, ni kasnije se ne predomisliste da mu povjerujete.”"},{"v":33,"t":"“Drugu prispodobu čujte! Bijaše neki domaćin koji posadi vinograd, ogradi ga ogradom, iskopa u njemu tijesak i podiže kulu pa ga iznajmi vinogradarima i otputova."},{"v":34,"t":"Kad se približilo vrijeme plodova, posla svoje sluge vinogradarima da uzmu njegov urod."},{"v":35,"t":"A vinogradari pograbe njegove sluge pa jednoga istukoše, drugog ubiše, a trećega kamenovaše."},{"v":36,"t":"I opet posla druge sluge, više njih nego prije, ali oni i s njima postupiše jednako.”"},{"v":37,"t":"“Naposljetku posla k njima sina svoga misleći: 'Poštovat će mog sina.'"},{"v":38,"t":"Ali kad vinogradari ugledaju sina, rekoše među sobom: 'Ovo je baštinik! Hajde da ga ubijemo i imat ćemo baštinu njegovu!'"},{"v":39,"t":"I pograbe ga, izbace iz vinograda i ubiju.”"},{"v":40,"t":"“Kada dakle dođe gospodar vinograda, što će učiniti s tim vinogradarima?”"},{"v":41,"t":"Kažu mu: “Opake će nemilo pogubiti, a vinograd iznajmiti drugim vinogradarima što će mu davati urod u svoje vrijeme.”"},{"v":42,"t":"Kaže im Isus: “Zar nikada niste čitali u Pismima: Kamen što ga odbaciše graditelji postade kamen zaglavni. Gospodnje je to djelo - kakvo čudo u očima našim!"},{"v":43,"t":"Zato će se - kažem vam - oduzeti od vas kraljevstvo Božje i dat će se narodu koji donosi njegove plodove! ("},{"v":44,"t":"I tko padne na taj kamen, smrskat će se, a na koga on padne, satrt će ga.)”"},{"v":45,"t":"Kad su glavari svećenički i farizeji čuli te njegove prispodobe, razumjeli su da govori o njima."},{"v":46,"t":"I tražili su da ga uhvate, ali se pobojaše mnoštva jer ga je smatralo prorokom."}]},"22":{"fa":[{"v":1,"t":"و عیسی توجه نموده، باز به مثلها ایشان را خطاب کرده، گفت:"},{"v":2,"t":"«ملکوت آسمان پادشاهی را ماند که برای پسر خویش عروسی کرد."},{"v":3,"t":"و غلامان خود را فرستاد تا دعوت‌شدگان را به عروسی بخوانند و نخواستند بیایند."},{"v":4,"t":"باز غلامان دیگر روانه نموده، فرمود: “دعوت‌شدگان را بگویید که اینک خوان خود را حاضر ساخته‌ام و گاوان و پرواریهای من کشته شده و همه‌چیز آماده است، به عروسی بیایید.”"},{"v":5,"t":"ولی ایشان بی‌اعتنایی نموده، راه خود را گرفتند، یکی به مزرعه خود و دیگری به تجارت خویش رفت."},{"v":6,"t":"و دیگران غلامان او را گرفته، دشنام داده، کشتند."},{"v":7,"t":"پادشاه چون شنید، غضب نموده، لشکریان خود را فرستاده، آن قاتلان را به قتل رسانید و شهر ایشان را بسوخت."},{"v":8,"t":"آنگاه غلامان خود را فرمود: “عروسی حاضر است؛ لیکن دعوت‌شدگان لیاقت نداشتند."},{"v":9,"t":"الان به شوارع عامه بروید و هر‌که را بیابید به عروسی بطلبید.”"},{"v":10,"t":"پس آن غلامان به‌سر راهها رفته، نیک و بد هرکه را یافتند جمع کردند، چنانکه خانه عروسی ازمجلسیان مملو گشت."},{"v":11,"t":"آنگاه پادشاه بجهت دیدن اهل مجلس داخل شده، شخصی را درآنجا دید که جامه عروسی در بر ندارد."},{"v":12,"t":"بدوگفت: “ای عزیز چطور در اینجا آمدی و حال آنکه جامه عروسی در بر نداری؟” او خاموش شد."},{"v":13,"t":"آنگاه پادشاه خادمان خود را فرمود: “این شخص را دست و پا بسته بردارید و در ظلمت خارجی اندازید، جایی که گریه و فشار دندان باشد.”"},{"v":14,"t":"زیرا طلبیدگان بسیارند و برگزیدگان کم.»"},{"v":15,"t":"پس فریسیان رفته، شورا نمودند که چطوراو را در گفتگو گرفتار سازند."},{"v":16,"t":"و شاگردان خودرا با هیرودیان نزد وی فرستاده، گفتند: «استادامی دانیم که صادق هستی و طریق خدا را به راستی تعلیم می‌نمایی و از کسی باک نداری زیراکه به ظاهر خلق نمی نگری."},{"v":17,"t":"پس به ما بگو رای تو چیست. آیا جزیه دادن به قیصر رواست یا نه؟»"},{"v":18,"t":"عیسی شرارت ایشان را درک کرده، گفت: «ای ریاکاران، چرا مرا تجربه می‌کنید؟"},{"v":19,"t":"سکه جزیه را به من بنمایید.» ایشان دیناری نزد وی آوردند."},{"v":20,"t":"بدیشان گفت: «این صورت و رقم از آن کیست؟»"},{"v":21,"t":"بدو گفتند: «از آن قیصر.» بدیشان گفت: «مال قیصر را به قیصر ادا کنید و مال خدا رابه خدا!»"},{"v":22,"t":"چون ایشان شنیدند، متعجب شدندو او را واگذارده، برفتند."},{"v":23,"t":"و در همان روز، صدوقیان که منکر قیامت هستند نزد او آمده، سوال نموده،"},{"v":24,"t":"گفتند: «ای استاد، موسی گفت اگر کسی بی‌اولاد بمیرد، می‌باید برادرش زن او را نکاح کند تا نسلی برای برادر خود پیدا نماید."},{"v":25,"t":"باری در میان ما هفت برادر بودند که اول زنی گرفته، بمرد و چون اولادی نداشت زن را به برادر خود ترک کرد."},{"v":26,"t":"وهمچنین دومین و سومین تا هفتمین."},{"v":27,"t":"و آخر ازهمه آن زن نیز مرد."},{"v":28,"t":"پس او در قیامت، زن کدام‌یک از آن هفت خواهد بود زیرا که همه او راداشتند؟»"},{"v":29,"t":"عیسی در جواب ایشان گفت: «گمراه هستید از این‌رو که کتاب و قوت خدا رادر نیافته‌اید،"},{"v":30,"t":"زیرا که در قیامت، نه نکاح می‌کنند و نه نکاح کرده می‌شوند بلکه مثل ملائکه خدا در آسمان می‌باشند."},{"v":31,"t":"اما درباره قیامت مردگان، آیا نخوانده‌اید کلامی را که خدا به شما گفته است،"},{"v":32,"t":"من هستم خدای ابراهیم و خدای اسحاق و خدای یعقوب؟ خدا، خدای مردگان نیست بلکه خدای زندگان است.»"},{"v":33,"t":"و آن گروه چون شنیدند، از تعلیم وی متحیر شدند."},{"v":34,"t":"اما چون فریسیان شنیدند که صدوقیان را مجاب نموده است، با هم جمع شدند."},{"v":35,"t":"و یکی از ایشان که فقیه بود، از وی به طریق امتحان سوال کرده، گفت:"},{"v":36,"t":"«ای استاد، کدام حکم در شریعت بزرگتر است؟»"},{"v":37,"t":"عیسی وی را گفت: «اینکه خداوند خدای خود را به همه دل و تمامی نفس و تمامی فکر خود محبت نما."},{"v":38,"t":"این است حکم اول و اعظم."},{"v":39,"t":"و دوم مثل آن است یعنی همسایه خود را مثل خود محبت نما."},{"v":40,"t":"بدین دو حکم، تمام تورات و صحف انبیامتعلق است.»"},{"v":41,"t":"و چون فریسیان جمع بودند، عیسی ازایشان پرسیده،"},{"v":42,"t":"گفت: «درباره مسیح چه گمان می‌برید؟ او پسر کیست؟» بدو گفتند: «پسر داود.»"},{"v":43,"t":"ایشان را گفت: «پس چطور داود در روح، او راخداوند می‌خواند؟ چنانکه می‌گوید:"},{"v":44,"t":"“خداوندبه خداوند من گفت، به‌دست راست من بنشین تادشمانان تو را پای انداز تو سازم.”"},{"v":45,"t":"پس هرگاه داود او را خداوند می‌خواند، چگونه پسرش می‌باشد؟»"},{"v":46,"t":"و هیچ‌کس قدرت جواب وی هرگز نداشت و نه کسی از آن روز دیگرجرات سوال کردن از او نمود."}],"en":[{"v":1,"t":"Jesus answered and spoke to them again in parables, saying,"},{"v":2,"t":"“The Kingdom of Heaven is like a certain king, who made a wedding feast for his son,"},{"v":3,"t":"and sent out his servants to call those who were invited to the wedding feast, but they would not come."},{"v":4,"t":"Again he sent out other servants, saying, ‘Tell those who are invited, “Behold, I have prepared my dinner. My cattle and my fatlings are killed, and all things are ready. Come to the wedding feast!”’"},{"v":5,"t":"But they made light of it, and went their ways, one to his own farm, another to his merchandise;"},{"v":6,"t":"and the rest grabbed his servants, treated them shamefully, and killed them."},{"v":7,"t":"When the king heard that, he was angry, and sent his armies, destroyed those murderers, and burned their city."},{"v":8,"t":"“Then he said to his servants, ‘The wedding is ready, but those who were invited weren’t worthy."},{"v":9,"t":"Go therefore to the intersections of the highways, and as many as you may find, invite to the wedding feast.’"},{"v":10,"t":"Those servants went out into the highways and gathered together as many as they found, both bad and good. The wedding was filled with guests."},{"v":11,"t":"“But when the king came in to see the guests, he saw there a man who didn’t have on wedding clothing,"},{"v":12,"t":"and he said to him, ‘Friend, how did you come in here not wearing wedding clothing?’ He was speechless."},{"v":13,"t":"Then the king said to the servants, ‘Bind him hand and foot, take him away, and throw him into the outer darkness. That is where the weeping and grinding of teeth will be.’"},{"v":14,"t":"For many are called, but few chosen.”"},{"v":15,"t":"Then the Pharisees went and took counsel how they might entrap him in his talk."},{"v":16,"t":"They sent their disciples to him, along with the Herodians, saying, “Teacher, we know that you are honest, and teach the way of God in truth, no matter whom you teach; for you aren’t partial to anyone."},{"v":17,"t":"Tell us therefore, what do you think? Is it lawful to pay taxes to Caesar, or not?”"},{"v":18,"t":"But Jesus perceived their wickedness, and said, “Why do you test me, you hypocrites?"},{"v":19,"t":"Show me the tax money.” They brought to him a denarius."},{"v":20,"t":"He asked them, “Whose is this image and inscription?”"},{"v":21,"t":"They said to him, “Caesar’s.” Then he said to them, “Give therefore to Caesar the things that are Caesar’s, and to God the things that are God’s.”"},{"v":22,"t":"When they heard it, they marveled, and left him and went away."},{"v":23,"t":"On that day Sadducees (those who say that there is no resurrection) came to him. They asked him,"},{"v":24,"t":"saying, “Teacher, Moses said, ‘If a man dies, having no children, his brother shall marry his wife and raise up offspring for his brother.’"},{"v":25,"t":"Now there were with us seven brothers. The first married and died, and having no offspring left his wife to his brother."},{"v":26,"t":"In the same way, the second also, and the third, to the seventh."},{"v":27,"t":"After them all, the woman died."},{"v":28,"t":"In the resurrection therefore, whose wife will she be of the seven? For they all had her.”"},{"v":29,"t":"But Jesus answered them, “You are mistaken, not knowing the Scriptures, nor the power of God."},{"v":30,"t":"For in the resurrection they neither marry nor are given in marriage, but are like God’s angels in heaven."},{"v":31,"t":"But concerning the resurrection of the dead, haven’t you read that which was spoken to you by God, saying,"},{"v":32,"t":"‘I am the God of Abraham, and the God of Isaac, and the God of Jacob’? God is not the God of the dead, but of the living.”"},{"v":33,"t":"When the multitudes heard it, they were astonished at his teaching."},{"v":34,"t":"But the Pharisees, when they heard that he had silenced the Sadducees, gathered themselves together."},{"v":35,"t":"One of them, a lawyer, asked him a question, testing him."},{"v":36,"t":"“Teacher, which is the greatest commandment in the law?”"},{"v":37,"t":"Jesus said to him, “‘You shall love the Lord your God with all your heart, with all your soul, and with all your mind.’"},{"v":38,"t":"This is the first and great commandment."},{"v":39,"t":"A second likewise is this, ‘You shall love your neighbor as yourself.’"},{"v":40,"t":"The whole law and the prophets depend on these two commandments.”"},{"v":41,"t":"Now while the Pharisees were gathered together, Jesus asked them a question,"},{"v":42,"t":"saying, “What do you think of the Christ? Whose son is he?” They said to him, “Of David.”"},{"v":43,"t":"He said to them, “How then does David in the Spirit call him Lord, saying,"},{"v":44,"t":"‘The Lord said to my Lord, sit on my right hand, until I make your enemies a footstool for your feet’?"},{"v":45,"t":"“If then David calls him Lord, how is he his son?”"},{"v":46,"t":"No one was able to answer him a word, neither did any man dare ask him any more questions from that day forward."}],"hr":[{"v":1,"t":"Isus im ponovno prozbori u prispodobama:"},{"v":2,"t":"“Kraljevstvo je nebesko kao kad neki kralj pripravi svadbu sinu svomu."},{"v":3,"t":"Posla sluge da pozovu uzvanike na svadbu. No oni ne htjedoše doći."},{"v":4,"t":"Opet posla druge sluge govoreći: 'Recite uzvanicima: Evo, objed sam ugotovio. Junci su moji i tovljenici poklani i sve pripravljeno. Dođite na svadbu!'”"},{"v":5,"t":"“Ali oni ne mareći odoše - jedan na svoju njivu, drugi za svojom trgovinom."},{"v":6,"t":"Ostali uhvate njegove sluge, zlostave ih i ubiju."},{"v":7,"t":"Nato se kralj razgnjevi, posla svoju vojsku i pogubi one ubojice, a grad im spali.”"},{"v":8,"t":"“Tada kaže slugama: 'Svadba je, evo, pripravljena ali uzvanici ne bijahu dostojni."},{"v":9,"t":"Pođite stoga na raskršća i koga god nađete, pozovite na svadbu!'”"},{"v":10,"t":"“Sluge iziđoše na putove i sabraše sve koje nađoše - i zle i dobre. I svadbena se dvorana napuni gostiju."},{"v":11,"t":"Kad kralj uđe pogledati goste, spazi ondje čovjeka koji ne bijaše odjeven u svadbeno ruho."},{"v":12,"t":"Kaže mu: 'Prijatelju, kako si ovamo ušao bez svadbenoga ruha?' A on zanijemi."},{"v":13,"t":"Tada kralj reče poslužiteljima: 'Svežite mu ruke i noge i bacite ga van u tamu, gdje će biti plač i škrgut zubi.'"},{"v":14,"t":"Doista, mnogo je zvanih, malo izabranih.”"},{"v":15,"t":"Tada farizeji odoše i održaše vijeće kako da Isusa uhvate u riječi."},{"v":16,"t":"Pošalju k njemu svoje učenike s herodovcima da ga upitaju: “Učitelju! Znamo da si istinit te po istini putu Božjem učiš i ne mariš tko je tko jer nisi pristran."},{"v":17,"t":"Reci nam, dakle, što ti se čini: je li dopušteno dati porez caru ili nije?”"},{"v":18,"t":"Znajući njihovu opakost, reče Isus: “Zašto me iskušavate, licemjeri?"},{"v":19,"t":"Pokažite mi porezni novac!” Pružiše mu denar."},{"v":20,"t":"On ih upita: “Čija je ovo slika i natpis?”"},{"v":21,"t":"Odgovore: “Carev.” Kaže im: “Podajte dakle caru carevo, a Bogu Božje.”"},{"v":22,"t":"Čuvši to, zadive se pa ga ostave i odu."},{"v":23,"t":"Toga dana pristupiše k njemu saduceji, koji vele da nema uskrsnuća, i upitaše ga:"},{"v":24,"t":"“Učitelju, Mojsije reče: Umre li tko bez djece, neka se njegov brat oženi njegovom ženom te podigne porod bratu svomu."},{"v":25,"t":"Bijaše tako u nas sedmero braće. Prvi se oženi i umrije bez poroda ostavivši ženu svom bratu."},{"v":26,"t":"Tako i drugi i treći, sve do sedmoga."},{"v":27,"t":"A nakon svih umrije i žena."},{"v":28,"t":"Kojemu će dakle od te sedmorice biti žena o uskrsnuću? Jer sva su je sedmorica imala.”"},{"v":29,"t":"Odgovori im Isus: “U zabludi ste jer ne razumijete Pisama ni sile Božje."},{"v":30,"t":"Ta u uskrsnuću niti se žene niti udavaju, nego su kao anđeli na nebu."},{"v":31,"t":"A što se tiče uskrsnuća mrtvih, zar niste čitali što vam reče Bog:"},{"v":32,"t":"Ja sam Bog Abrahamov, Bog Izakov i Bog Jakovljev? Nije on Bog mrtvih, nego živih!”"},{"v":33,"t":"Čuvši to, mnoštvo osta zaneseno njegovim naukom."},{"v":34,"t":"A kad su farizeji čuli kako ušutka saduceje, okupiše se,"},{"v":35,"t":"a jedan od njih, zakonoznanac, da ga iskuša, upita:"},{"v":36,"t":"“Učitelju, koja ja zapovijed najveća u Zakonu?”"},{"v":37,"t":"A on mu reče: “Ljubi Gospodina Boga svojega svim srcem svojim, i svom dušom svojom, i svim umom svojim."},{"v":38,"t":"To je najveća i prva zapovijed."},{"v":39,"t":"Druga, ovoj slična: Ljubi svoga bližnjega kao sebe samoga."},{"v":40,"t":"O tim dvjema zapovijedima visi sav Zakon i Proroci.”"},{"v":41,"t":"Kad se farizeji skupiše, upita ih Isus:"},{"v":42,"t":"“Što mislite o Kristu? Čiji je on sin?” Kažu mu: “Davidov.”"},{"v":43,"t":"A on će njima: “Kako ga onda David u Duhu naziva Gospodinom, kad veli:"},{"v":44,"t":"Reče Gospod Gospodinu mojemu: 'Sjedi mi zdesna dok ne položim neprijatelje tvoje za podnožje nogama tvojim?'"},{"v":45,"t":"Ako ga dakle David naziva Gospodinom, kako mu je sin?”"},{"v":46,"t":"I nitko mu nije mogao odgovoriti ni riječi, niti se od toga dana tko usudio upitati ga bilo što."}]},"23":{"fa":[{"v":1,"t":"آنگاه عیسی آن جماعت و شاگردان خود را خطاب کرده،"},{"v":2,"t":"گفت: «کاتبان وفریسیان بر کرسی موسی نشسته‌اند."},{"v":3,"t":"پس آنچه به شما گویند، نگاه دارید و به‌جا آورید، لیکن مثل اعمال ایشان مکنید زیرا می‌گویند ونمی کنند."},{"v":4,"t":"زیرا بارهای گران و دشوار رامی بندند و بر دوش مردم می‌نهند و خودنمی خواهند آنها را به یک انگشت حرکت دهند."},{"v":5,"t":"و همه کارهای خود را می‌کنند تا مردم، ایشان را ببینند. حمایلهای خود را عریض و دامنهای قبای خود را پهن می‌سازند،"},{"v":6,"t":"و بالا نشستن درضیافتها و کرسیهای صدر در کنایس را دوست می‌دارند،"},{"v":7,"t":"و تعظیم در کوچه‌ها را و اینکه مردم ایشان را آقا آقا بخوانند."},{"v":8,"t":"لیکن شماآقا خوانده مشوید، زیرا استاد شما یکی است یعنی مسیح و جمیع شما برادرانید."},{"v":9,"t":"و هیچ‌کس را بر زمین، پدر خود مخوانید زیرا پدر شمایکی است که در آسمان است."},{"v":10,"t":"و پیشواخوانده مشوید، زیرا پیشوای شما یکی است یعنی مسیح."},{"v":11,"t":"و هر‌که از شما بزرگتر باشد، خادم شما بود."},{"v":12,"t":"و هر‌که خود را بلند کند، پست گردد و هر‌که خود را فروتن سازد سرافرازگردد."},{"v":13,"t":"وای بر شما‌ای کاتبان و فریسیان ریاکار که در ملکوت آسمان را به روی مردم می‌بندید، زیراخود داخل آن نمی شوید و داخل‌شوندگان را ازدخول مانع می‌شوید."},{"v":14,"t":"وای بر شما‌ای کاتبان وفریسیان ریاکار، زیرا خانه های بیوه‌زنان رامی بلعید و از روی ریا نماز را طویل می‌کنید؛ ازآنرو عذاب شدیدتر خواهید یافت."},{"v":15,"t":"وای برشما‌ای کاتبان و فریسیان ریاکار، زیرا که بر و بحررا می‌گردید تا مریدی پیدا کنید و چون پیدا شداو را دو مرتبه پست‌تر از خود، پسر جهنم می‌سازید!"},{"v":16,"t":"وای بر شما‌ای راهنمایان کور که می‌گویید “هر‌که به هیکل قسم خورد باکی نیست لیکن هر‌که به طلای هیکل قسم خورد باید وفاکند.”"},{"v":17,"t":"‌ای نادانان و نابینایان، آیا کدام افضل است؟ طلا یا هیکلی که طلا را مقدس می‌سازد؟"},{"v":18,"t":"“و هر‌که به مذبح قسم خورد باکی نیست لیکن هر‌که به هدیه‌ای که بر آن است قسم خورد، بایدادا کند.”"},{"v":19,"t":"‌ای جهال و کوران، کدام افضل است؟ هدیه یا مذبح که هدیه را تقدیس می‌نماید؟"},{"v":20,"t":"پس هر‌که به مذبح قسم خورد، به آن و به هرچه بر آن است قسم خورده است؛"},{"v":21,"t":"و هر‌که به هیکل قسم خورد، به آن و به او که در آن ساکن است، قسم خورده است؛"},{"v":22,"t":"و هر‌که به آسمان قسم خورد، به کرسی خدا و به او که بر آن نشسته است، قسم خورده باشد."},{"v":23,"t":"وای بر شما‌ای کاتبان و فریسیان ریاکار که نعناع و شبت و زیره را عشر می‌دهید و اعظم احکام شریعت، یعنی عدالت و رحمت و ایمان را ترک کرده‌اید! می‌بایست آنها را به‌جا آورده، اینها را نیز ترک نکرده باشید."},{"v":24,"t":"‌ای رهنمایان کورکه پشه را صافی می‌کنید و شتر را فرو می‌برید!"},{"v":25,"t":"وای بر شما‌ای کاتبان و فریسیان ریاکار، از آن رو که بیرون پیاله و بشقاب را پاک می‌نمایید ودرون آنها مملو از جبر و ظلم است."},{"v":26,"t":"‌ای فریسی کور، اول درون پیاله و بشقاب را طاهرساز تا بیرونش نیز طاهر شود!"},{"v":27,"t":"وای بر شما‌ای کاتبان و فریسیان ریاکار که چون قبور سفید شده می‌باشید که از بیرون، نیکو می‌نماید لیکن درون آنها از استخوانهای مردگان و سایر نجاسات پراست!"},{"v":28,"t":"همچنین شما نیز ظاهر به مردم عادل می‌نمایید، لیکن باطن از ریاکاری و شرارت مملوهستید."},{"v":29,"t":"وای بر شما‌ای کاتبان و فریسیان ریاکار که قبرهای انبیا را بنا می‌کنید و مدفنهای صادقان رازینت می‌دهید،"},{"v":30,"t":"و می‌گویید: “اگر در ایام پدران خود می‌بودیم، در ریختن خون انبیا با ایشان شریک نمی شدیم!”"},{"v":31,"t":"پس بر خود شهادت می‌دهید که فرزندان قاتلان انبیا هستید."},{"v":32,"t":"پس شما پیمانه پدران خود را لبریز کنید!"},{"v":33,"t":"‌ای ماران و افعی‌زادگان! چگونه از عذاب جهنم فرارخواهید کرد؟"},{"v":34,"t":"لهذا الحال انبیا و حکماء وکاتبان نزد شما می‌فرستم و بعضی را خواهیدکشت و به دار خواهید کشید و بعضی را درکنایس خود تازیانه زده، از شهر به شهر خواهیدراند،"},{"v":35,"t":"تا همه خونهای صادقان که بر زمین ریخته شد بر شما وارد آید، از خون هابیل صدیق تا خون زکریا ابن برخیا که او را در میان هیکل ومذبح کشتید."},{"v":36,"t":"هرآینه به شما می‌گویم که این همه بر این طایفه خواهد آمد!"},{"v":37,"t":"«ای اورشلیم، اورشلیم، قاتل انبیا وسنگسار کننده مرسلان خود! چند مرتبه‌خواستم فرزندان تو را جمع کنم، مثل مرغی که جوجه های خود را زیر بال خود جمع می‌کند ونخواستید!"},{"v":38,"t":"اینک خانه شما برای شما ویران گذارده می‌شود."},{"v":39,"t":"زیرا به شما می‌گویم از این پس مرا نخواهید دید تا بگویید مبارک است او که به نام خداوند می‌آید.»"}],"en":[{"v":1,"t":"Then Jesus spoke to the multitudes and to his disciples,"},{"v":2,"t":"saying, “The scribes and the Pharisees sit on Moses’ seat."},{"v":3,"t":"All things therefore whatever they tell you to observe, observe and do, but don’t do their works; for they say, and don’t do."},{"v":4,"t":"For they bind heavy burdens that are grievous to be borne, and lay them on men’s shoulders; but they themselves will not lift a finger to help them."},{"v":5,"t":"But they do all their works to be seen by men. They make their phylacteries broad and enlarge the fringes of their garments,"},{"v":6,"t":"and love the place of honor at feasts, the best seats in the synagogues,"},{"v":7,"t":"the salutations in the marketplaces, and to be called ‘Rabbi, Rabbi’ by men."},{"v":8,"t":"But you are not to be called ‘Rabbi’, for one is your teacher, the Christ, and all of you are brothers."},{"v":9,"t":"Call no man on the earth your father, for one is your Father, he who is in heaven."},{"v":10,"t":"Neither be called masters, for one is your master, the Christ."},{"v":11,"t":"But he who is greatest among you will be your servant."},{"v":12,"t":"Whoever exalts himself will be humbled, and whoever humbles himself will be exalted."},{"v":13,"t":"“Woe to you, scribes and Pharisees, hypocrites! For you devour widows’ houses, and as a pretense you make long prayers. Therefore you will receive greater condemnation."},{"v":14,"t":"“But woe to you, scribes and Pharisees, hypocrites! Because you shut up the Kingdom of Heaven against men; for you don’t enter in yourselves, neither do you allow those who are entering in to enter."},{"v":15,"t":"Woe to you, scribes and Pharisees, hypocrites! For you travel around by sea and land to make one proselyte; and when he becomes one, you make him twice as much a son of Gehenna as yourselves."},{"v":16,"t":"“Woe to you, you blind guides, who say, ‘Whoever swears by the temple, it is nothing; but whoever swears by the gold of the temple, he is obligated.’"},{"v":17,"t":"You blind fools! For which is greater, the gold or the temple that sanctifies the gold?"},{"v":18,"t":"And, ‘Whoever swears by the altar, it is nothing; but whoever swears by the gift that is on it, he is obligated.’"},{"v":19,"t":"You blind fools! For which is greater, the gift, or the altar that sanctifies the gift?"},{"v":20,"t":"He therefore who swears by the altar, swears by it and by everything on it."},{"v":21,"t":"He who swears by the temple, swears by it and by him who has been living in it."},{"v":22,"t":"He who swears by heaven, swears by the throne of God and by him who sits on it."},{"v":23,"t":"“Woe to you, scribes and Pharisees, hypocrites! For you tithe mint, dill, and cumin, and have left undone the weightier matters of the law: justice, mercy, and faith. But you ought to have done these, and not to have left the other undone."},{"v":24,"t":"You blind guides, who strain out a gnat, and swallow a camel!"},{"v":25,"t":"“Woe to you, scribes and Pharisees, hypocrites! For you clean the outside of the cup and of the platter, but within they are full of extortion and unrighteousness."},{"v":26,"t":"You blind Pharisee, first clean the inside of the cup and of the platter, that its outside may become clean also."},{"v":27,"t":"“Woe to you, scribes and Pharisees, hypocrites! For you are like whitened tombs, which outwardly appear beautiful, but inwardly are full of dead men’s bones and of all uncleanness."},{"v":28,"t":"Even so you also outwardly appear righteous to men, but inwardly you are full of hypocrisy and iniquity."},{"v":29,"t":"“Woe to you, scribes and Pharisees, hypocrites! For you build the tombs of the prophets and decorate the tombs of the righteous,"},{"v":30,"t":"and say, ‘If we had lived in the days of our fathers, we wouldn’t have been partakers with them in the blood of the prophets.’"},{"v":31,"t":"Therefore you testify to yourselves that you are children of those who killed the prophets."},{"v":32,"t":"Fill up, then, the measure of your fathers."},{"v":33,"t":"You serpents, you offspring of vipers, how will you escape the judgment of Gehenna?"},{"v":34,"t":"Therefore, behold, I send to you prophets, wise men, and scribes. Some of them you will kill and crucify; and some of them you will scourge in your synagogues and persecute from city to city,"},{"v":35,"t":"that on you may come all the righteous blood shed on the earth, from the blood of righteous Abel to the blood of Zachariah son of Barachiah, whom you killed between the sanctuary and the altar."},{"v":36,"t":"Most certainly I tell you, all these things will come upon this generation."},{"v":37,"t":"“Jerusalem, Jerusalem, who kills the prophets and stones those who are sent to her! How often I would have gathered your children together, even as a hen gathers her chicks under her wings, and you would not!"},{"v":38,"t":"Behold, your house is left to you desolate."},{"v":39,"t":"For I tell you, you will not see me from now on, until you say, ‘Blessed is he who comes in the name of the Lord!’”"}],"hr":[{"v":1,"t":"Tada Isus prozbori mnoštvu i svojim učenicima:"},{"v":2,"t":"“Na Mojsijevu stolicu zasjedoše pismoznanci i farizeji."},{"v":3,"t":"Činite dakle i obdržavajte sve što vam kažu, ali se nemojte ravnati po njihovim djelima jer govore, a ne čine."},{"v":4,"t":"Vežu i ljudima na pleća tovare teška bremena, a sami ni da bi ih prstom makli."},{"v":5,"t":"Sva svoja djela čine zato da ih ljudi vide. Doista, proširuju zapise svoje i produljuju rese."},{"v":6,"t":"Vole pročelja na gozbama, prva sjedala u sinagogama,"},{"v":7,"t":"pozdrave na trgovima i da ih ljudi zovu 'Rabbi'."},{"v":8,"t":"Vi pak ne dajte se zvati 'Rabbi', jer jedan je učitelj vaš, a svi ste vi braća."},{"v":9,"t":"Ni ocem ne zovite nikoga na zemlji jer jedan je Otac vaš - onaj na nebesima."},{"v":10,"t":"I ne dajte da vas vođama zovu, jer jedan je vaš vođa - Krist."},{"v":11,"t":"Najveći među vama neka vam bude poslužitelj."},{"v":12,"t":"Tko se god uzvisuje, bit će ponižen, a tko se ponizuje, bit će uzvišen.”"},{"v":13,"t":"“Jao vama, pismoznanci i farizeji! Licemjeri! Zaključavate kraljevstvo nebesko pred ljudima; sami ne ulazite, a ne date ući ni onima koji bi htjeli.”"},{"v":14,"t":"#"},{"v":15,"t":"“Jao vama, pismoznanci i farizeji! Licemjeri! Obilazite morem i kopnom da pridobijete jednog sljedbenika. A kad ga pridobijete, promećete ga u sina paklenoga dvaput goreg od sebe.”"},{"v":16,"t":"“Jao vama! Slijepe vođe! Govorite: 'Zakune li se tko Hramom, nije ništa. Ali ako se zakune hramskim zlatom, veže ga zakletva.'"},{"v":17,"t":"Budale i slijepci! Ta što je veće: zlato ili Hram što posvećuje zlato?"},{"v":18,"t":"Nadalje: 'Zakune li se tko žrtvenikom, nije ništa. Ali ako se zakune darom što je na njemu, veže ga zakletva.'"},{"v":19,"t":"Slijepci! Ta što je veće: dar ili žrtvenik što dar posvećuje?"},{"v":20,"t":"Tko se dakle zakune žrtvenikom, kune se njime i svime što je na njemu."},{"v":21,"t":"I tko se zakune Hramom, kune se njime i Onim koji u njemu prebiva."},{"v":22,"t":"I tko se zakune nebom, kune se prijestoljem Božjim i Onim koji na njemu sjedi.”"},{"v":23,"t":"“Jao vama, pismoznanci i farizeji! Licemjeri! Namirujete desetinu od metvice i kopra i kima, a propuštate najvažnije u Zakonu: pravednost, milosrđe, vjernost. Ovo je trebalo činiti, a ono ne propuštati."},{"v":24,"t":"Slijepe vođe! Cijedite komarca, a gutate devu!”"},{"v":25,"t":"“Jao vama, pismoznanci i farizeji! Licemjeri! Čistite čašu i zdjelu izvana, a iznutra su pune grabeža i pohlepe."},{"v":26,"t":"Farizeju slijepi! Očisti najprije nutrinu čaše da joj i vanjština bude čista.”"},{"v":27,"t":"Jao vama pismoznanci i farizeji! Licemjeri! Nalik ste na obijeljene grobove. Izvana izgledaju lijepi, a iznutra su puni mrtvačkih kostiju i svakojake nečistoće."},{"v":28,"t":"Tako i vi izvana ljudima izgledate pravedni, a iznutra ste puni licemjerja i bezakonja.”"},{"v":29,"t":"“Jao vama, pismoznanci i farizeji! Licemjeri! Gradite grobnice prorocima i kitite spomenike pravednicima"},{"v":30,"t":"te govorite: 'Da smo mi živjeli u dane otaca svojih, ne bismo bili njihovi sudionici u prolijevanju krvi proročke.'"},{"v":31,"t":"Tako sami protiv sebe svjedočite da ste sinovi ubojica proroka."},{"v":32,"t":"Dopunite samo mjeru otaca svojih!”"},{"v":33,"t":"“Zmije! Leglo gujinje! Kako ćete uteći osudi paklenoj?"},{"v":34,"t":"Zato evo ja šaljem vama proroke i mudrace i pismoznance. Jedne ćete od njih ubiti i raspeti, druge bičevati po svojim sinagogama i progoniti od grada do grada"},{"v":35,"t":"da tako na vas dođe sva pravedna krv, prolivena na zemlji od krvi Abela pravednoga pa do krvi Zaharije, sina Barahijina, kojega ubiste između Hrama i žrtvenika."},{"v":36,"t":"Zaista, kažem vam, sve će to doći na ovaj naraštaj!”"},{"v":37,"t":"“Jeruzaleme, Jeruzaleme, koji ubijaš proroke i kamenuješ one što su tebi poslani! Koliko li puta htjedoh okupiti djecu tvoju kao što kvočka okuplja piliće pod krila, i ne htjedoste."},{"v":38,"t":"Evo, napuštena vam kuća."},{"v":39,"t":"Doista, kažem vam, odsada me nećete vidjeti dok ne reknete: Blagoslovljen Onaj koji dolazi u ime Gospodnje!”"}]},"24":{"fa":[{"v":1,"t":"پس عیسی از هیکل بیرون شده، برفت. و شاگردانش پیش آمدند تا عمارتهای هیکل را بدو نشان دهند."},{"v":2,"t":"عیسی ایشان را گفت: «آیا همه این چیزها را نمی بینید؟ هرآینه به شمامی گویم در اینجا سنگی بر سنگی گذارده نخواهد شد که به زیر افکنده نشود!»"},{"v":3,"t":"و چون به کوه زیتون نشسته بود، شاگردانش در خلوت نزدوی آمده، گفتند: «به ما بگو که این امور کی واقع می‌شود و نشان آمدن تو و انقضای عالم چیست.»"},{"v":4,"t":"عیسی در جواب ایشان گفت: «زنهار کسی شما را گمراه نکند!"},{"v":5,"t":"زآنرو که بسا به نام من آمده خواهند گفت که من مسیح هستم و بسیاری را گمراه خواهند کرد."},{"v":6,"t":"و جنگها و اخبار جنگها راخواهید شنید. زنهار مضطرب مشوید زیرا که وقوع این همه لازم است، لیکن انتها هنوز نیست."},{"v":7,"t":"زیرا قومی با قومی و مملکتی با مملکتی مقاومت خواهند نمود و قحطیها و وباها وزلزله‌ها در جایها پدید آید."},{"v":8,"t":"اما همه اینها آغازدردهای زه است."},{"v":9,"t":"آنگاه شما را به مصیبت سپرده، خواهند کشت و جمیع امت‌ها بجهت اسم من از شما نفرت کنند."},{"v":10,"t":"و در آن زمان، بسیاری لغزش خورده، یکدیگر را تسلیم کنند واز یکدیگر نفرت گیرند."},{"v":11,"t":"و بسا انبیای کذبه ظاهر شده، بسیاری را گمراه کنند."},{"v":12,"t":"و بجهت افزونی گناه محبت بسیاری سرد خواهد شد."},{"v":13,"t":"لیکن هر‌که تا به انتها صبر کند، نجات یابد."},{"v":14,"t":"و به این بشارت ملکوت در تمام عالم موعظه خواهد شد تا بر جمیع امت‌ها شهادتی شود؛ آنگاه انتها خواهد رسید."},{"v":15,"t":"«پس چون مکروه ویرانی را که به زبان دانیال نبی گفته شده است، در مقام مقدس بر پاشده بینید هر‌که خواند دریافت کند"},{"v":16,"t":"آنگاه هر‌که در یهودیه باشد به کوهستان بگریزد؛"},{"v":17,"t":"وهر‌که بر بام باشد، بجهت برداشتن چیزی از خانه به زیر نیاید؛"},{"v":18,"t":"و هر‌که در مزرعه است، بجهت برداشتن رخت خود برنگردد."},{"v":19,"t":"لیکن وای برآبستنان و شیر دهندگان در آن ایام!"},{"v":20,"t":"پس دعاکنید تا فرار شما در زمستان یا در سبت نشود،"},{"v":21,"t":"زیرا که در آن زمان چنان مصیبت عظیمی ظاهر می‌شود که از ابتدا عالم تا کنون نشده ونخواهد شد!"},{"v":22,"t":"و اگر آن ایام کوتاه نشدی، هیچ بشری نجات نیافتی، لیکن بخاطر برگزیدگان، آن روزها کوتاه خواهد شد."},{"v":23,"t":"آنگاه اگر کسی به شما گوید: “اینک مسیح در اینجا یا در آنجا است “ باور مکنید،"},{"v":24,"t":"زیرا که مسیحیان کاذب و انبیا کذبه ظاهر شده، علامات ومعجزات عظیمه چنان خواهند نمود که اگرممکن بودی برگزیدگان را نیز گمراه کردندی."},{"v":25,"t":"اینک شما را پیش خبر دادم."},{"v":26,"t":"«پس اگر شما را گویند: اینک درصحراست، بیرون مروید یا آنکه در خلوت است، باور مکنید،"},{"v":27,"t":"زیرا همچنان‌که برق ازمشرق ساطع شده، تا به مغرب ظاهر می‌شود، ظهور پسر انسان نیز چنین خواهد شد."},{"v":28,"t":"و هرجا که مرداری باشد، کرکسان در آنجا جمع شوند."},{"v":29,"t":"و فور بعد از مصیبت آن ایام، آفتاب تاریک گردد و ماه نور خود را ندهد و ستارگان ازآسمان فرو ریزند و قوتهای افلاک متزلزل گردد."},{"v":30,"t":"آنگاه علامت پسر انسان در آسمان پدید گرددو در آن وقت، جمیع طوایف زمین سینه زنی کنندو پسر انسان را بینند که بر ابرهای آسمان، با قوت و جلال عظیم می‌آید؛"},{"v":31,"t":"و فرشتگان خود را باصور بلند آواز فرستاده، برگزیدگان او را ازبادهای اربعه از کران تا بکران فلک فراهم خواهندآورد."},{"v":32,"t":"«پس از درخت انجیر مثلش را فرا‌گیرید که چون شاخه‌اش نازک شده، برگها می‌آورد، می فهمید که تابستان نزدیک است."},{"v":33,"t":"همچنین شما نیز چون این همه را بینید، بفهمید که نزدیک بلکه بر در است."},{"v":34,"t":"هرآینه به شما می‌گویم تا این همه واقع نشود، این طایفه نخواهد گذشت."},{"v":35,"t":"آسمان و زمین زایل خواهد شد، لیکن سخنان من هرگز زایل نخواهد شد."},{"v":36,"t":"«اما از آن روز و ساعت هیچ‌کس اطلاع ندارد، حتی ملائکه آسمان جز پدر من و بس."},{"v":37,"t":"لیکن چنانکه ایام نوح بود، ظهور پسر انسان نیزچنان خواهد بود."},{"v":38,"t":"زیرا همچنان‌که در ایام قبل از طوفان می‌خوردند و می‌آشامیدند و نکاح می‌کردند و منکوحه می‌شدند تا روزی که نوح داخل کشتی گشت،"},{"v":39,"t":"و نفهمیدند تا طوفان آمده، همه را ببرد، همچنین ظهور پسر انسان نیزخواهد بود."},{"v":40,"t":"آنگاه دو نفری که در مزرعه‌ای می‌باشند، یکی گرفته و دیگری واگذارده شود."},{"v":41,"t":"و دو زن که دستاس می‌کنند، یکی گرفته ودیگری رها شود."},{"v":42,"t":"پس بیدار باشید زیرا که نمی دانید در کدام ساعت خداوند شما می‌آید."},{"v":43,"t":"لیکن این را بدانید که اگر صاحب‌خانه می‌دانست در چه پاس از شب دزد می‌آید، بیدارمی ماند و نمی گذاشت که به خانه‌اش نقب زند."},{"v":44,"t":"لهذا شما نیز حاضر باشید، زیرا در ساعتی که گمان نبرید، پسر انسان می‌آید."},{"v":45,"t":"«پس آن غلام امین و دانا کیست که آقایش او را بر اهل خانه خود بگمارد تا ایشان را در وقت معین خوراک دهد؟"},{"v":46,"t":"خوشابحال آن غلامی که چون آقایش آید، او را در چنین کار مشغول یابد."},{"v":47,"t":"هرآینه به شما می‌گویم که او را بر تمام مایملک خود خواهد گماشت."},{"v":48,"t":"لیکن هرگاه آن غلام شریر با خود گوید که آقای من در‌آمدن تاخیر می‌نماید،"},{"v":49,"t":"و شروع کند به زدن همقطاران خود و خوردن و نوشیدن با میگساران،"},{"v":50,"t":"هرآینه آقای آن غلام آید، در روزی که منتظرنباشد و در ساعتی که نداند،"},{"v":51,"t":"و او را دو پاره کرده، نصیبش را با ریاکاران قرار دهد در مکانی که گریه و فشار دندان خواهد بود."}],"en":[{"v":1,"t":"Jesus went out from the temple, and was going on his way. His disciples came to him to show him the buildings of the temple."},{"v":2,"t":"But he answered them, “You see all of these things, don’t you? Most certainly I tell you, there will not be left here one stone on another, that will not be thrown down.”"},{"v":3,"t":"As he sat on the Mount of Olives, the disciples came to him privately, saying, “Tell us, when will these things be? What is the sign of your coming, and of the end of the age?”"},{"v":4,"t":"Jesus answered them, “Be careful that no one leads you astray."},{"v":5,"t":"For many will come in my name, saying, ‘I am the Christ,’ and will lead many astray."},{"v":6,"t":"You will hear of wars and rumors of wars. See that you aren’t troubled, for all this must happen, but the end is not yet."},{"v":7,"t":"For nation will rise against nation, and kingdom against kingdom; and there will be famines, plagues, and earthquakes in various places."},{"v":8,"t":"But all these things are the beginning of birth pains."},{"v":9,"t":"“Then they will deliver you up to oppression and will kill you. You will be hated by all of the nations for my name’s sake."},{"v":10,"t":"Then many will stumble, and will deliver up one another, and will hate one another."},{"v":11,"t":"Many false prophets will arise and will lead many astray."},{"v":12,"t":"Because iniquity will be multiplied, the love of many will grow cold."},{"v":13,"t":"But he who endures to the end will be saved."},{"v":14,"t":"This Good News of the Kingdom will be preached in the whole world for a testimony to all the nations, and then the end will come."},{"v":15,"t":"“When, therefore, you see the abomination of desolation, which was spoken of through Daniel the prophet, standing in the holy place (let the reader understand),"},{"v":16,"t":"then let those who are in Judea flee to the mountains."},{"v":17,"t":"Let him who is on the housetop not go down to take out the things that are in his house."},{"v":18,"t":"Let him who is in the field not return back to get his clothes."},{"v":19,"t":"But woe to those who are with child and to nursing mothers in those days!"},{"v":20,"t":"Pray that your flight will not be in the winter nor on a Sabbath,"},{"v":21,"t":"for then there will be great suffering, such as has not been from the beginning of the world until now, no, nor ever will be."},{"v":22,"t":"Unless those days had been shortened, no flesh would have been saved. But for the sake of the chosen ones, those days will be shortened."},{"v":23,"t":"“Then if any man tells you, ‘Behold, here is the Christ!’ or, ‘There!’ don’t believe it."},{"v":24,"t":"For false christs and false prophets will arise, and they will show great signs and wonders, so as to lead astray, if possible, even the chosen ones."},{"v":25,"t":"“Behold, I have told you beforehand."},{"v":26,"t":"“If therefore they tell you, ‘Behold, he is in the wilderness,’ don’t go out; or ‘Behold, he is in the inner rooms,’ don’t believe it."},{"v":27,"t":"For as the lightning flashes from the east, and is seen even to the west, so will the coming of the Son of Man be."},{"v":28,"t":"For wherever the carcass is, that is where the vultures gather together."},{"v":29,"t":"“But immediately after the suffering of those days, the sun will be darkened, the moon will not give its light, the stars will fall from the sky, and the powers of the heavens will be shaken;"},{"v":30,"t":"and then the sign of the Son of Man will appear in the sky. Then all the tribes of the earth will mourn, and they will see the Son of Man coming on the clouds of the sky with power and great glory."},{"v":31,"t":"He will send out his angels with a great sound of a trumpet, and they will gather together his chosen ones from the four winds, from one end of the sky to the other."},{"v":32,"t":"“Now from the fig tree learn this parable: When its branch has now become tender and produces its leaves, you know that the summer is near."},{"v":33,"t":"Even so you also, when you see all these things, know that he is near, even at the doors."},{"v":34,"t":"Most certainly I tell you, this generation will not pass away until all these things are accomplished."},{"v":35,"t":"Heaven and earth will pass away, but my words will not pass away."},{"v":36,"t":"“But no one knows of that day and hour, not even the angels of heaven, but my Father only."},{"v":37,"t":"As the days of Noah were, so will the coming of the Son of Man be."},{"v":38,"t":"For as in those days which were before the flood they were eating and drinking, marrying and giving in marriage, until the day that Noah entered into the ship,"},{"v":39,"t":"and they didn’t know until the flood came and took them all away, so will the coming of the Son of Man be."},{"v":40,"t":"Then two men will be in the field: one will be taken and one will be left."},{"v":41,"t":"Two women will be grinding at the mill: one will be taken and one will be left."},{"v":42,"t":"Watch therefore, for you don’t know in what hour your Lord comes."},{"v":43,"t":"But know this, that if the master of the house had known in what watch of the night the thief was coming, he would have watched, and would not have allowed his house to be broken into."},{"v":44,"t":"Therefore also be ready, for in an hour that you don’t expect, the Son of Man will come."},{"v":45,"t":"“Who then is the faithful and wise servant, whom his lord has set over his household, to give them their food in due season?"},{"v":46,"t":"Blessed is that servant whom his lord finds doing so when he comes."},{"v":47,"t":"Most certainly I tell you that he will set him over all that he has."},{"v":48,"t":"But if that evil servant should say in his heart, ‘My lord is delaying his coming,’"},{"v":49,"t":"and begins to beat his fellow servants, and eat and drink with the drunkards,"},{"v":50,"t":"the lord of that servant will come in a day when he doesn’t expect it and in an hour when he doesn’t know it,"},{"v":51,"t":"and will cut him in pieces and appoint his portion with the hypocrites. That is where the weeping and grinding of teeth will be."}],"hr":[{"v":1,"t":"Isus iziđe iz Hrama. Putom mu pristupiše učenici pokazujući mu hramsko zdanje."},{"v":2,"t":"A on im reče: “Ne vidite li sve ovo? Zaista, kažem vam, ne, neće se ovdje ostaviti ni kamen na kamenu nerazvaljen.”"},{"v":3,"t":"Dok je zatim na Maslinskoj gori sjedio, pristupiše k njemu učenici nasamo govoreći: “Reci nam kada će to biti i koji će biti znak tvojega Dolaska i svršetka svijeta?”"},{"v":4,"t":"Isus im odgovori: “Pazite da vas tko ne zavede!"},{"v":5,"t":"Mnogi će doista doći u moje ime i govoriti: 'Ja sam Krist!' I mnoge će zavesti.”"},{"v":6,"t":"“A čut ćete za ratove i za glasove o ratovima. Pazite, ne uznemirujte se. Doista treba da se to dogodi, ali to još nije svršetak."},{"v":7,"t":"Narod će ustati protiv naroda i kraljevstvo protiv kraljevstva; bit će gladi i potresa po raznim mjestima."},{"v":8,"t":"Ali sve je to samo početak trudova.”"},{"v":9,"t":"“Tada će vas predavati na muke i ubijati vas. I svi će vas narodi zamrziti zbog imena moga."},{"v":10,"t":"Mnogi će se tada sablazniti, izdavat će jedni druge i mrziti se među sobom."},{"v":11,"t":"Ustat će mnogi lažni proroci i mnoge zavesti."},{"v":12,"t":"Razmahat će se bezakonje i ohladnjeti ljubav mnogih."},{"v":13,"t":"Ali tko ustraje do svršetka, bit će spašen.”"},{"v":14,"t":"“I propovijedat će se ovo evanđelje Kraljevstva po svem svijetu za svjedočanstvo svim narodima. Tada će doći svršetak.”"},{"v":15,"t":"“Kada dakle vidite da grozota pustoši, po proroštvu Daniela proroka, stoluje na svetome mjestu - tko čita, neka razumije:"},{"v":16,"t":"koji se tada zateknu u Judeji, neka bježe u gore;"},{"v":17,"t":"tko bude na krovu, neka ne silazi uzeti što iz kuće;"},{"v":18,"t":"i tko bude u polju, neka se ne okreće natrag da uzme haljinu!”"},{"v":19,"t":"“A jao trudnicama i dojiljama u one dane!”"},{"v":20,"t":"“I molite da bijeg vaš ne bude zimi ili subotom"},{"v":21,"t":"jer tada će biti velika tjeskoba kakve ne bijaše od početka svijeta sve do sada, a neće je ni biti.”"},{"v":22,"t":"“I kad se ne bi skratili dani oni, nitko se ne bi spasio. No poradi izabranih skratit će se dani oni.”"},{"v":23,"t":"“Ako vam tada tko rekne: 'Gle, evo Krista!' ili: 'Eno ga!' - ne povjerujte!"},{"v":24,"t":"Ustat će, doista, lažni kristi i lažni proroci i iznijeti znamenja velika i čudesa da, bude li moguće, zavedu i izabrane.”"},{"v":25,"t":"“Eto, prorekao sam vam.”"},{"v":26,"t":"“Reknu li vam dakle: 'Evo, u pustinji je!', ne izlazite; 'Evo ga u ložnicama!', ne vjerujte."},{"v":27,"t":"Jer kao što munja izlazi od istoka i bljesne do zapada, tako će biti i s dolaskom Sina Čovječjega.”"},{"v":28,"t":"“Gdje bude strvine, ondje će se skupljati orlovi.”"},{"v":29,"t":"“A odmah nakon nevolje onih dana sunce će pomrčati i mjesec neće više svijetljeti i zvijezde će s neba padati i sile će se nebeske poljuljati.”"},{"v":30,"t":"“I tada će se pojaviti znak Sina Čovječjega na nebu. I tada će proplakati sva plemena zemlje. I ugledat će Sina Čovječjega gdje dolazi na oblacima nebeskim s velikom moći i slavom."},{"v":31,"t":"I razaslat će anđele svoje s trubljom velikom i sabrat će mu izabranike s četiri vjetra, s jednoga kraja neba do drugoga.”"},{"v":32,"t":"“A od smokve se naučite prispodobi! Kad joj grana već omekša i lišće potjera, znate: blizu je ljeto."},{"v":33,"t":"Tako i vi kad sve to ugledate, znajte: blizu je, na vratima!”"},{"v":34,"t":"“Zaista, kažem vam, ne, neće uminuti naraštaj ovaj dok se sve to ne zbude."},{"v":35,"t":"Nebo će i zemlja uminuti, ali riječi moje ne, neće uminuti.”"},{"v":36,"t":"“A o onom danu i času nitko ne zna, pa ni anđeli nebeski, ni Sin, nego samo Otac."},{"v":37,"t":"Kao u dane Noine, tako će biti i Dolazak Sina Čovječjega."},{"v":38,"t":"Kao što su u dane one - prije potopa - jeli i pili, ženili se i udavali do dana kad Noa uđe u korablju"},{"v":39,"t":"i ništa nisu ni slutili dok ne dođe potop i sve odnije - tako će biti i Dolazak Sina Čovječjega."},{"v":40,"t":"Dvojica će tada biti u polju: jedan će se uzeti, drugi ostaviti."},{"v":41,"t":"Dvije će mljeti u mlinu: jedna će se uzeti, druga ostaviti.”"},{"v":42,"t":"“Bdijte dakle jer ne znate u koji dan Gospodin vaš dolazi."},{"v":43,"t":"A ovo znajte: kad bi domaćin znao o kojoj straži kradljivac dolazi, bdio bi i ne bi dopustio potkopati kuće."},{"v":44,"t":"Zato i vi budite pripravni jer u čas kad i ne mislite Sin Čovječji dolazi.”"},{"v":45,"t":"“Tko li je onaj vjerni i razumni sluga što ga gospodar postavi nad svojim ukućanima da im izda hranu u pravo vrijeme?"},{"v":46,"t":"Blago onome sluzi kojega gospodar kada dođe nađe da tako radi!"},{"v":47,"t":"Zaista, kažem vam, postavit će ga nad svim imanjem svojim.”"},{"v":48,"t":"“No rekne li taj zli sluga u srcu: 'Okasnit će gospodar moj'"},{"v":49,"t":"pa stane tući sudrugove, jesti i piti s pijanicama,"},{"v":50,"t":"doći će gospodar toga sluge u dan u koji mu se ne nada i u čas u koji i ne sluti;"},{"v":51,"t":"rasjeći će ga i dodijeliti mu udes među licemjerima. Ondje će biti plač i škrgut zubi.”"}]},"25":{"fa":[{"v":1,"t":"«در آن زمان ملکوت آسمان مثل ده باکره خواهد بود که مشعلهای خود رابرداشته، به استقبال داماد بیرون رفتند."},{"v":2,"t":"و ازایشان پنج دانا و پنج نادان بودند."},{"v":3,"t":"اما نادانان مشعلهای خود را برداشته، هیچ روغن با خودنبردند."},{"v":4,"t":"لیکن دانایان، روغن در ظروف خود بامشعلهای خویش برداشتند."},{"v":5,"t":"و چون آمدن دامادبطول انجامید، همه پینکی زده، خفتند."},{"v":6,"t":"و درنصف شب صدایی بلند شد که “اینک دامادمی آید به استقبال وی بشتابید.”"},{"v":7,"t":"پس تمامی آن باکره‌ها برخاسته، مشعلهای خود را اصلاح نمودند."},{"v":8,"t":"و نادانان، دانایان را گفتند: “از روغن خود به ما دهید زیرا مشعلهای ما خاموش می‌شود.”"},{"v":9,"t":"اما دانایان در جواب گفتند: “نمی شود، مبادا ما و شما را کفاف ندهد. بلکه نزدفروشندگان رفته، برای خود بخرید.”"},{"v":10,"t":"و درحینی که ایشان بجهت خرید می‌رفتند، داماد برسید و آنانی که حاضر بودند، با وی به عروسی داخل شده، در بسته گردید."},{"v":11,"t":"بعد از آن، باکره های دیگر نیز آمده، گفتند: “خداوندا برای ماباز کن.”"},{"v":12,"t":"او در جواب گفت: “هرآینه به شمامی گویم شما را نمی شناسم.”"},{"v":13,"t":"پس بیدار باشیدزیرا که آن روز و ساعت را نمی دانید."},{"v":14,"t":"«زیرا چنانکه مردی عازم سفر شده، غلامان خود را طلبید و اموال خود را بدیشان سپرد،"},{"v":15,"t":"یکی را پنج قنطار و دیگری را دو وسومی را یک داد؛ هر یک را بحسب استعدادش. و بی‌درنگ متوجه سفر شد."},{"v":16,"t":"پس آنکه پنج قنطار یافته بود، رفته و با آنها تجارت نموده، پنج قنطار دیگر سود کرد."},{"v":17,"t":"و همچنین صاحب دوقنطار نیز دو قنطار دیگر سود گرفت."},{"v":18,"t":"اما آنکه یک قنطار گرفته بود، رفته زمین را کند و نقد آقای خود را پنهان نمود."},{"v":19,"t":"«و بعد از مدت مدیدی، آقای آن غلامان آمده، از ایشان حساب خواست."},{"v":20,"t":"پس آنکه پنج قنطار یافته بود، پیش آمده، پنج قنطار دیگرآورده، گفت: خداوندا پنج قنطار به من سپردی، اینک پنج قنطار دیگر سود کردم.”"},{"v":21,"t":"آقای او به وی گفت: آفرین‌ای غلام نیک متدین! بر چیزهای اندک امین بودی، تو را بر چیزهای بسیار خواهم گماشت. به شادی خداوند خود داخل شو!"},{"v":22,"t":"وصاحب دو قنطار نیز آمده، گفت: ای آقا دو قنطارتسلیم من نمودی، اینک دو قنطار دیگر سودیافته‌ام."},{"v":23,"t":"آقایش وی را گفت: آفرین‌ای غلام نیک متدین! بر چیزهای کم امین بودی، تو را بر چیزهای بسیار می‌گمارم. در خوشی خداوندخود داخل شو!"},{"v":24,"t":"پس آنکه یک قنطار گرفته بود، پیش آمده، گفت: ای آقا چون تو رامی شناختم که مرد درشت خویی می‌باشی، ازجایی که نکاشته‌ای می‌دروی و از جایی که نیفشانده‌ای جمع می‌کنی،"},{"v":25,"t":"پس ترسان شده، رفتم و قنطار تو را زیر زمین نهفتم. اینک مال توموجود است."},{"v":26,"t":"آقایش در جواب وی گفت: ای غلام شریر بیکاره! دانسته‌ای که از جایی که نکاشته‌ام میدروم و از مکانی که نپاشیده‌ام، جمع می‌کنم."},{"v":27,"t":"از همین جهت تو را می‌بایست نقد مرابه صرافان بدهی تا وقتی که بیایم مال خود را باسود بیابم."},{"v":28,"t":"الحال آن قنطار را از او گرفته، به صاحب ده قنطار بدهید."},{"v":29,"t":"زیرا به هر‌که داردداده شود و افزونی یابد و از آنکه ندارد آنچه داردنیز گرفته شود."},{"v":30,"t":"و آن غلام بی‌نفع را در ظلمت خارجی اندازید، جایی که گریه و فشار دندان خواهد بود."},{"v":31,"t":"«اما چون پسر انسان در جلال خود باجمیع ملائکه مقدس خویش آید، آنگاه بر کرسی جلال خود خواهد نشست،"},{"v":32,"t":"و جمیع امت‌ها درحضور او جمع شوند و آنها را از همدیگر جدامی کند به قسمی که شبان میشها را از بزها جدامی کند."},{"v":33,"t":"و میشها را بر دست راست و بزها را برچپ خود قرار دهد."},{"v":34,"t":"آنگاه پادشاه به اصحاب طرف راست گوید: بیایید‌ای برکت یافتگان از پدر من و ملکوتی را که از ابتدای عالم برای شما آماده‌شده است، به میراث گیرید."},{"v":35,"t":"زیرا چون گرسنه بودم مرا طعام دادید، تشنه بودم سیرآبم نمودید، غریب بودم مرا جا دادید،"},{"v":36,"t":"عریان بودم مراپوشانیدید، مریض بودم عیادتم کردید، در حبس بودم دیدن من آمدید."},{"v":37,"t":"آنگاه عادلان به پاسخ گویند: ای خداوند، کی گرسنه ات دیدیم تاطعامت دهیم، یا تشنه ات یافتیم تا سیرآبت نماییم،"},{"v":38,"t":"یا کی تو را غریب یافتیم تا تو را جادهیم یا عریان تا بپوشانیم،"},{"v":39,"t":"و کی تو را مریض یامحبوس یافتیم تا عیادتت کنیم؟"},{"v":40,"t":"پادشاه درجواب ایشان گوید: هرآینه به شما می‌گویم، آنچه به یکی از این برادران کوچکترین من کردید، به من کرده‌اید."},{"v":41,"t":"«پس اصحاب طرف چپ را گوید: ای ملعونان، از من دور شوید در آتش جاودانی که برای ابلیس و فرشتگان او مهیا شده است."},{"v":42,"t":"زیراگرسنه بودم مرا خوراک ندادید، تشنه بودم مراآب ندادید،"},{"v":43,"t":"غریب بودم مرا جا ندادید، عریان بودم مرا نپوشانیدید، مریض و محبوس بودم عیادتم ننمودید."},{"v":44,"t":"پس ایشان نیز به پاسخ گویند: ای خداوند، کی تو را گرسنه یا تشنه یاغریب یا برهنه یا مریض یا محبوس دیده، خدمتت نکردیم؟"},{"v":45,"t":"آنگاه در جواب ایشان گوید: هرآینه به شما می‌گویم، آنچه به یکی از این کوچکان نکردید، به من نکرده‌اید."},{"v":46,"t":"و ایشان درعذاب جاودانی خواهند رفت، اما عادلان درحیات جاودانی.»"}],"en":[{"v":1,"t":"“Then the Kingdom of Heaven will be like ten virgins who took their lamps and went out to meet the bridegroom."},{"v":2,"t":"Five of them were foolish, and five were wise."},{"v":3,"t":"Those who were foolish, when they took their lamps, took no oil with them,"},{"v":4,"t":"but the wise took oil in their vessels with their lamps."},{"v":5,"t":"Now while the bridegroom delayed, they all slumbered and slept."},{"v":6,"t":"But at midnight there was a cry, ‘Behold! The bridegroom is coming! Come out to meet him!’"},{"v":7,"t":"Then all those virgins arose, and trimmed their lamps."},{"v":8,"t":"The foolish said to the wise, ‘Give us some of your oil, for our lamps are going out.’"},{"v":9,"t":"But the wise answered, saying, ‘What if there isn’t enough for us and you? You go rather to those who sell, and buy for yourselves.’"},{"v":10,"t":"While they went away to buy, the bridegroom came, and those who were ready went in with him to the wedding feast, and the door was shut."},{"v":11,"t":"Afterward the other virgins also came, saying, ‘Lord, Lord, open to us.’"},{"v":12,"t":"But he answered, ‘Most certainly I tell you, I don’t know you.’"},{"v":13,"t":"Watch therefore, for you don’t know the day nor the hour in which the Son of Man is coming."},{"v":14,"t":"“For it is like a man going into another country, who called his own servants and entrusted his goods to them."},{"v":15,"t":"To one he gave five talents, to another two, to another one, to each according to his own ability. Then he went on his journey."},{"v":16,"t":"Immediately he who received the five talents went and traded with them, and made another five talents."},{"v":17,"t":"In the same way, he also who got the two gained another two."},{"v":18,"t":"But he who received the one talent went away and dug in the earth and hid his lord’s money."},{"v":19,"t":"“Now after a long time the lord of those servants came, and settled accounts with them."},{"v":20,"t":"He who received the five talents came and brought another five talents, saying, ‘Lord, you delivered to me five talents. Behold, I have gained another five talents in addition to them.’"},{"v":21,"t":"“His lord said to him, ‘Well done, good and faithful servant. You have been faithful over a few things, I will set you over many things. Enter into the joy of your lord.’"},{"v":22,"t":"“He also who got the two talents came and said, ‘Lord, you delivered to me two talents. Behold, I have gained another two talents in addition to them.’"},{"v":23,"t":"“His lord said to him, ‘Well done, good and faithful servant. You have been faithful over a few things. I will set you over many things. Enter into the joy of your lord.’"},{"v":24,"t":"“He also who had received the one talent came and said, ‘Lord, I knew you that you are a hard man, reaping where you didn’t sow, and gathering where you didn’t scatter."},{"v":25,"t":"I was afraid, and went away and hid your talent in the earth. Behold, you have what is yours.’"},{"v":26,"t":"“But his lord answered him, ‘You wicked and slothful servant. You knew that I reap where I didn’t sow, and gather where I didn’t scatter."},{"v":27,"t":"You ought therefore to have deposited my money with the bankers, and at my coming I should have received back my own with interest."},{"v":28,"t":"Take away therefore the talent from him and give it to him who has the ten talents."},{"v":29,"t":"For to everyone who has will be given, and he will have abundance, but from him who doesn’t have, even that which he has will be taken away."},{"v":30,"t":"Throw out the unprofitable servant into the outer darkness, where there will be weeping and gnashing of teeth.’"},{"v":31,"t":"“But when the Son of Man comes in his glory, and all the holy angels with him, then he will sit on the throne of his glory."},{"v":32,"t":"Before him all the nations will be gathered, and he will separate them one from another, as a shepherd separates the sheep from the goats."},{"v":33,"t":"He will set the sheep on his right hand, but the goats on the left."},{"v":34,"t":"Then the King will tell those on his right hand, ‘Come, blessed of my Father, inherit the Kingdom prepared for you from the foundation of the world;"},{"v":35,"t":"for I was hungry and you gave me food to eat. I was thirsty and you gave me drink. I was a stranger and you took me in."},{"v":36,"t":"I was naked and you clothed me. I was sick and you visited me. I was in prison and you came to me.’"},{"v":37,"t":"“Then the righteous will answer him, saying, ‘Lord, when did we see you hungry and feed you, or thirsty and give you a drink?"},{"v":38,"t":"When did we see you as a stranger and take you in, or naked and clothe you?"},{"v":39,"t":"When did we see you sick or in prison and come to you?’"},{"v":40,"t":"“The King will answer them, ‘Most certainly I tell you, because you did it to one of the least of these my brothers, you did it to me.’"},{"v":41,"t":"Then he will say also to those on the left hand, ‘Depart from me, you cursed, into the eternal fire which is prepared for the devil and his angels;"},{"v":42,"t":"for I was hungry, and you didn’t give me food to eat; I was thirsty, and you gave me no drink;"},{"v":43,"t":"I was a stranger, and you didn’t take me in; naked, and you didn’t clothe me; sick, and in prison, and you didn’t visit me.’"},{"v":44,"t":"“Then they will also answer, saying, ‘Lord, when did we see you hungry, or thirsty, or a stranger, or naked, or sick, or in prison, and didn’t help you?’"},{"v":45,"t":"“Then he will answer them, saying, ‘Most certainly I tell you, because you didn’t do it to one of the least of these, you didn’t do it to me.’"},{"v":46,"t":"These will go away into eternal punishment, but the righteous into eternal life.”"}],"hr":[{"v":1,"t":"“Tada će kraljevstvo nebesko biti kao kad deset djevica uzeše svoje svjetiljke i iziđoše u susret zaručniku."},{"v":2,"t":"Pet ih bijaše ludih, a pet mudrih."},{"v":3,"t":"Lude uzeše svjetiljke, ali ne uzeše sa sobom ulja."},{"v":4,"t":"Mudre pak zajedno sa svjetiljkama uzeše u posudama ulja.”"},{"v":5,"t":"“Budući da je zaručnik okasnio, sve one zadrijemaše i pozaspaše."},{"v":6,"t":"O ponoći nasta vika: 'Evo zaručnika! Iziđite mu u susret!'"},{"v":7,"t":"Tada ustadoše sve one djevice i urediše svoje svjetiljke."},{"v":8,"t":"Lude tada rekoše mudrima: 'Dajte nam od svoga ulja, gase nam se svjetiljke!'"},{"v":9,"t":"Mudre im odgovore: 'Nipošto! Ne bi doteklo nama i vama. Pođite radije k prodavačima i kupite!'”"},{"v":10,"t":"“Dok one odoše kupiti, dođe zaručnik: koje bijahu pripravne, uđoše s njim na svadbu i zatvore se vrata."},{"v":11,"t":"Poslije dođu i ostale djevice pa stanu dozivati: 'Gospodine! Gospodine! Otvori nam!'"},{"v":12,"t":"A on im odgovori: 'Zaista kažem vam, ne poznam vas!'"},{"v":13,"t":"Bdijte dakle jer ne znate dana ni časa!”"},{"v":14,"t":"“Doista, kao kad ono čovjek, polazeći na put, dozva sluge i dade im svoj imetak."},{"v":15,"t":"Jednomu dade pet talenata, drugomu dva, a trećemu jedan - svakomu po njegovoj sposobnosti."},{"v":16,"t":"I otputova. Onaj koji je primio pet talenata odmah ode, upotrijebi ih i stekne drugih pet."},{"v":17,"t":"Isto tako i onaj sa dva stekne druga dva."},{"v":18,"t":"Onaj naprotiv koji je primio jedan ode, otkopa zemlju i sakri novac gospodarov.”"},{"v":19,"t":"“Nakon dugo vremena dođe gospodar tih slugu i zatraži od njih račun."},{"v":20,"t":"Pristupi mu onaj što je primio pet talenata i donese drugih pet govoreći: 'Gospodaru! Pet si mi talenata predao. Evo, drugih sam pet talenata stekao!'"},{"v":21,"t":"Reče mu gospodar: 'Valjaš, slugo dobri i vjerni! U malome si bio vjeran, nad mnogim ću te postaviti! Uđi u radost gospodara svoga!'”"},{"v":22,"t":"“Pristupi i onaj sa dva talenta te reče: 'Gospodaru! Dva si mi talenta predao. Evo, druga sam dva talenta stekao!'"},{"v":23,"t":"Reče mu gospodar: 'Valjaš, slugo dobri i vjerni! U malome si bio vjeran, nad mnogim ću te postaviti! Uđi u radost gospodara svoga.'”"},{"v":24,"t":"“A pristupi i onaj koji je primio jedan talenat te reče: 'Gospodaru! Znadoh te: čovjek si strog, žanješ gdje nisi sijao i kupiš gdje nisi vijao."},{"v":25,"t":"Pobojah se stoga, odoh i sakrih talenat tvoj u zemlju. Evo ti tvoje!'"},{"v":26,"t":"A gospodar mu reče: 'Slugo zli i lijeni! Znao si da žanjem gdje nisam sijao i kupim gdje nisam vijao!"},{"v":27,"t":"Trebalo je dakle da uložiš moj novac kod novčara i ja bih po povratku izvadio svoje s dobitkom.'”"},{"v":28,"t":"“'Uzmite stoga od njega talenat i podajte onomu koji ih ima deset."},{"v":29,"t":"Doista, onomu koji ima još će se dati, neka ima u izobilju, a od onoga koji nema oduzet će se i ono što ima."},{"v":30,"t":"A beskorisnoga slugu izbacite van u tamu. Ondje će biti plač i škrgut zubi.'”"},{"v":31,"t":"“Kad Sin Čovječji dođe u slavi i svi anđeli njegovi s njime, sjest će na prijestolje slave svoje."},{"v":32,"t":"I sabrat će se pred njim svi narodi, a on će ih jedne od drugih razlučiti kao što pastir razlučuje ovce od jaraca."},{"v":33,"t":"Postavit će ovce sebi zdesna, a jarce slijeva.”"},{"v":34,"t":"“Tada će kralj reći onima sebi zdesna: 'Dođite, blagoslovljeni Oca mojega! Primite u baštinu Kraljevstvo pripravljeno za vas od postanka svijeta!"},{"v":35,"t":"Jer ogladnjeh i dadoste mi jesti; ožednjeh i napojiste me; stranac bijah i primiste me;"},{"v":36,"t":"gol i zaogrnuste me; oboljeh i pohodiste me; u tamnici bijah i dođoste k meni.'”"},{"v":37,"t":"“Tada će mu pravednici odgovoriti: 'Gospodine, kada te to vidjesmo gladna i nahranismo te; ili žedna i napojismo te?"},{"v":38,"t":"Kada te vidjesmo kao stranca i primismo; ili gola i zaogrnusmo te?"},{"v":39,"t":"Kada te vidjesmo bolesna ili u tamnici i dođosmo k tebi?'"},{"v":40,"t":"A kralj će im odgovoriti: 'Zaista, kažem vam, što god učiniste jednomu od ove moje najmanje braće, meni učiniste!'”"},{"v":41,"t":"“Zatim će reći i onima slijeva: 'Odlazite od mene, prokleti, u oganj vječni, pripravljen đavlu i anđelima njegovim!"},{"v":42,"t":"Jer ogladnjeh i ne dadoste mi jesti; ožednjeh i ne dadoste mi piti;"},{"v":43,"t":"stranac bijah i ne primiste me; gol i ne zaogrnuste me; bolestan i u tamnici i ne pohodiste me!'”"},{"v":44,"t":"“Tada će mu i oni odgovoriti: 'Gospodine, a kada te to vidjesmo gladna, ili žedna, ili stranca, ili gola, ili bolesna, ili u tamnici, i ne poslužismo te?'"},{"v":45,"t":"Tada će im on odgovoriti: 'Zaista, kažem vam, što god ne učiniste jednomu od ovih najmanjih, ni meni ne učiniste.'”"},{"v":46,"t":"“I otići će ovi u muku vječnu, a pravednici u život vječni.”"}]},"26":{"fa":[{"v":1,"t":"و چون عیسی همه این سخنان را به اتمام رسانید، به شاگردان خود گفت:"},{"v":2,"t":"«می‌دانید که بعد از دو روز عید فصح است که پسر انسان تسلیم کرده می‌شود تا مصلوب گردد.»"},{"v":3,"t":"آنگاه روسای کهنه و کاتبان و مشایخ قوم دردیوانخانه رئیس کهنه که قیافا نام داشت جمع شده،"},{"v":4,"t":"شورا نمودند تا عیسی را به حیله گرفتارساخته، به قتل رسانند."},{"v":5,"t":"اما گفتند: «نه در وقت عید مبادا آشوبی در قوم بر پا شود.»"},{"v":6,"t":"و هنگامی که عیسی در بیت عنیا در خانه شمعون ابرص شد،"},{"v":7,"t":"زنی با شیشه‌ای عطر گرانبهانزد او آمده، چون بنشست بر سر وی ریخت."},{"v":8,"t":"اماشاگردانش چون این را دیدند، غضب نموده، گفتند: «چرا این اسراف شده است؟"},{"v":9,"t":"زیرا ممکن بود این عطر به قیمت گران فروخته و به فقرا داده شود.»"},{"v":10,"t":"عیسی این را درک کرده، بدیشان گفت: «چرا بدین زن زحمت می‌دهید؟ زیرا کار نیکو به من کرده است."},{"v":11,"t":"زیرا که فقرا را همیشه نزد خوددارید اما مرا همیشه ندارید."},{"v":12,"t":"و این زن که این عطر را بر بدنم مالید، بجهت دفن من کرده است."},{"v":13,"t":"هرآینه به شما می‌گویم هر جایی که درتمام عالم بدین بشارت موعظه کرده شود، کاراین زن نیز بجهت یادگاری او مذکور خواهدشد.»"},{"v":14,"t":"«آنگاه یکی از آن دوازده که به یهودای اسخریوطی مسمی بود، نزد روسای کهنه رفته،"},{"v":15,"t":"گفت: «مرا چند خواهید داد تا او را به شماتسلیم کنم؟ «ایشان سی پاره نقره با وی قراردادند."},{"v":16,"t":"و از آن وقت در صدد فرصت شد تا اورا بدیشان تسلیم کند."},{"v":17,"t":"پس در روز اول عید فطیر، شاگردان نزدعیسی آمده، گفتند: «کجا می‌خواهی فصح راآماده کنیم تا بخوری؟»"},{"v":18,"t":"گفت: «به شهر، نزدفلان کس رفته، بدو گویید: “استاد می‌گوید وقت من نزدیک شد و فصح را در خانه تو با شاگردان خود صرف می‌نمایم.”»"},{"v":19,"t":"شاگردان چنانکه عیسی ایشان را امر فرمود کردند و فصح را مهیاساختند."},{"v":20,"t":"چون وقت شام رسید با آن دوازده بنشست."},{"v":21,"t":"و وقتی که ایشان غذا می‌خوردند، اوگفت: «هرآینه به شما می‌گویم که یکی از شما مراتسلیم می‌کند!»"},{"v":22,"t":"پس بغایت غمگین شده، هریک از ایشان به وی سخن آغاز کردند که «خداوندا آیا من آنم؟»"},{"v":23,"t":"او در جواب گفت: «آنکه دست با من در قاب فرو برد، همان کس مرا تسلیم نماید!"},{"v":24,"t":"هرآینه پسر انسان به همانطور که درباره او مکتوب است رحلت می‌کند. لیکن وای بر آنکسی‌که پسر انسان بدست او تسلیم شود! آن شخص را بهتر بودی که تولد نیافتی!»"},{"v":25,"t":"و یهوداکه تسلیم‌کننده وی بود، به جواب گفت: «ای استاد آیا من آنم؟» به وی گفت: «تو خود گفتی!»"},{"v":26,"t":"و چون ایشان غذا می‌خوردند، عیسی نان راگرفته، برکت داد و پاره کرده، به شاگردان داد وگفت: «بگیرید و بخورید، این است بدن من.»"},{"v":27,"t":"وپیاله را گرفته، شکر نمود و بدیشان داده، گفت: «همه شما از این بنوشید،"},{"v":28,"t":"زیرا که این است خون من در عهد جدید که در راه بسیاری بجهت آمرزش گناهان ریخته می‌شود."},{"v":29,"t":"اما به شمامی گویم که بعد از این از میوه مو دیگر نخواهم نوشید تا روزی که آن را با شما در ملکوت پدرخود، تازه آشامم.»"},{"v":30,"t":"پس تسبیح خواندند و به سوی کوه زیتون روانه شدند."},{"v":31,"t":"آنگاه عیسی بدیشان گفت: «همه شما امشب درباره من لغزش می‌خورید چنانکه مکتوب است که شبان را می‌زنم و گوسفندان گله پراکنده می‌شوند."},{"v":32,"t":"لیکن بعد از برخاستنم، پیش از شما به جلیل خواهم رفت.»"},{"v":33,"t":"پطرس درجواب وی گفت: «هر گاه همه درباره تو لغزش خورند، من هرگز نخورم.»"},{"v":34,"t":"عیسی به وی گفت: «هرآینه به تو می‌گویم که در همین شب قبل ازبانک زدن خروس، سه مرتبه مرا انکار خواهی کرد!»"},{"v":35,"t":"پطرس به وی گفت: «هرگاه مردنم با تو لازم شود، هرگز تو را انکار نکنم!» و سایرشاگردان نیز همچنان گفتند."},{"v":36,"t":"آنگاه عیسی با ایشان به موضعی که مسمی به جتسیمانی بود رسیده، به شاگردان خود گفت: «در اینجا بنشینید تا من رفته، در آنجا دعا کنم.»"},{"v":37,"t":"و پطرس و دو پسر زبدی را برداشته، بی‌نهایت غمگین و دردناک شد."},{"v":38,"t":"پس بدیشان گفت: «نفس من از غایت الم مشرف به موت شده است. در اینجا مانده با من بیدار باشید.»"},{"v":39,"t":"پس قدری پیش رفته، به روی در‌افتاد و دعا کرده، گفت: «ای پدر من، اگر ممکن باشد این پیاله از من بگذرد؛ لیکن نه به خواهش من، بلکه به اراداه تو.»"},{"v":40,"t":"و نزدشاگردان خود آمده، ایشان را در خواب یافت. وبه پطرس گفت: «آیا همچنین نمی توانستید یک ساعت با من بیدار باشید؟"},{"v":41,"t":"بیدار باشید و دعاکنید تا در معرض آزمایش نیفتید! روح راغب است، لیکن جسم ناتوان.»"},{"v":42,"t":"و بار دیگر رفته، بازدعا نموده، گفت: «ای پدر من، اگر ممکن نباشد که این پیاله بدون نوشیدن از من بگذرد، آنچه اراده تواست بشود.»"},{"v":43,"t":"و آمده، باز ایشان را در خواب یافت زیرا که چشمان ایشان سنگین شده بود."},{"v":44,"t":"پس ایشان را ترک کرده، رفت و دفعه سوم به همان کلام دعا کرد."},{"v":45,"t":"آنگاه نزد شاگردان آمده، بدیشان گفت: «مابقی را بخوابید واستراحت کنید. الحال ساعت رسیده است که پسر انسان به‌دست گناهکاران تسلیم شود."},{"v":46,"t":"برخیزید برویم. اینک تسلیم‌کننده من نزدیک است!»"},{"v":47,"t":"و هنوز سخن می‌گفت که ناگاه یهودا که یکی از آن دوازده بود با جمعی کثیر با شمشیرهاو چوبها از جانب روساء کهنه و مشایخ قوم آمدند."},{"v":48,"t":"و تسلیم‌کننده او بدیشان نشانی داده، گفته بود: «هر‌که را بوسه زنم، همان است. او رامحکم بگیرید.»"},{"v":49,"t":"در ساعت نزد عیسی آمده، گفت: «سلام یا سیدی!» و او را بوسید."},{"v":50,"t":"عیسی وی را گفت: «ای رفیق، از بهر‌چه آمدی؟» آنگاه پیش آمده، دست بر عیسی انداخته، او را گرفتند."},{"v":51,"t":"و ناگاه یکی از همراهان عیسی دست آورده، شمشیر خود را از غلاف کشیده، بر غلام رئیس کهنه زد و گوشش را از تن جدا کرد."},{"v":52,"t":"آنگاه عیسی وی را گفت: «شمشیر خود را غلاف کن، زیرا هر‌که شمشیر گیرد، به شمشیر هلاک گردد."},{"v":53,"t":"آیا گمان می‌بری که نمی توانم الحال از پدرخود درخواست کنم که زیاده از دوازده فوج ازملائکه برای من حاضر سازد؟"},{"v":54,"t":"لیکن در این صورت کتب چگونه تمام گردد که همچنین می‌بایست بشود؟»"},{"v":55,"t":"در آن ساعت، به آن گروه گفت: گویا بر دزد بجهت گرفتن من با تیغها وچوبها بیرون آمدید! هر روز با شما در هیکل نشسته، تعلیم می‌دادم و مرا نگرفتید."},{"v":56,"t":"لیکن این همه شد تا کتب انبیا تمام شود.» در آن وقت جمیع شاگردان او را واگذارده، بگریختند."},{"v":57,"t":"و آنانی که عیسی را گرفته بودند، او را نزدقیافا رئیس کهنه جایی که کاتبان و مشایخ جمع بودند، بردند."},{"v":58,"t":"اما پطرس از دور در عقب اوآمده، به خانه رئیس کهنه در‌آمد و با خادمان بنشست تا انجام کار را ببیند."},{"v":59,"t":"پس روسای کهنه و مشایخ و تمامی اهل شورا طلب شهادت دروغ بر عیسی می‌کردند تا او را بقتل رسانند،"},{"v":60,"t":"لیکن نیافتند. با آنکه چند شاهد دروغ پیش آمدند، هیچ نیافتند. آخر دو نفر آمده،"},{"v":61,"t":"گفتند: «این شخص گفت: “می توانم هیکل خدا را خراب کنم و در سه روزش بنا نمایم.”»"},{"v":62,"t":"پس رئیس کهنه برخاسته، بدو گفت: «هیچ جواب نمی دهی؟ چیست که اینها بر تو شهادت می‌دهند؟»"},{"v":63,"t":"اما عیسی خاموش ماند! تا آنکه رئیس کهنه روی به وی کرده، گفت: «تو را به خدای حی قسم می‌دهم مارا بگوی که تو مسیح پس خدا هستی یا نه؟»"},{"v":64,"t":"عیسی به وی گفت: «تو گفتی! و نیز شما رامی گویم بعد از این پسر انسان را خواهید دید که بر دست راست قوت نشسته، بر ابرهای آسمان می‌آید!»"},{"v":65,"t":"در ساعت رئیس کهنه رخت خود راچاک زده، گفت: «کفر گفت! دیگر ما را چه حاجت به شهود است؟ الحال کفرش را شنیدید!"},{"v":66,"t":"چه مصلحت می‌بینید؟» ایشان در جواب گفتند: «مستوجب قتل است!»"},{"v":67,"t":"آنگاه آب دهان بر رویش انداخته، او را طپانچه می‌زدند و بعضی سیلی زده،"},{"v":68,"t":"می‌گفتند: «ای مسیح، به ما نبوت کن! کیست که تو را زده است؟»"},{"v":69,"t":"اما پطرس در ایوان بیرون نشسته بود که ناگاه کنیزکی نزد وی آمده، گفت: «تو هم با عیسی جلیلی بودی!»"},{"v":70,"t":"او روبروی همه انکارنموده، گفت: «نمی دانم چه می‌گویی!»"},{"v":71,"t":"و چون به دهلیز بیرون رفت، کنیزی دیگر او را دیده، به حاضرین گفت: «این شخص نیز از رفقای عیسی ناصری است!»"},{"v":72,"t":"باز قسم خورده، انکار نمود که «این مرد را نمی شناسم.»"},{"v":73,"t":"بعد از چندی، آنانی که ایستاده بودند پیش آمده، پطرس را گفتند: «البته تو هم از اینها هستی زیرا که لهجه تو بر تودلالت می‌نماید!»"},{"v":74,"t":"پس آغاز لعن کردن و قسم خوردن نمود که «این شخص را نمی شناسم.» ودر ساعت خروس بانگ زد"},{"v":75,"t":"آنگاه پطرس سخن عیسی را به یاد آورد که گفته بود: قبل از بانگ زدن خروس، سه مرتبه مرا انکار خواهی کرد.» پس بیرون رفته زار‌زار بگریست."}],"en":[{"v":1,"t":"When Jesus had finished all these words, he said to his disciples,"},{"v":2,"t":"“You know that after two days the Passover is coming, and the Son of Man will be delivered up to be crucified.”"},{"v":3,"t":"Then the chief priests, the scribes, and the elders of the people were gathered together in the court of the high priest, who was called Caiaphas."},{"v":4,"t":"They took counsel together that they might take Jesus by deceit and kill him."},{"v":5,"t":"But they said, “Not during the feast, lest a riot occur among the people.”"},{"v":6,"t":"Now when Jesus was in Bethany, in the house of Simon the leper,"},{"v":7,"t":"a woman came to him having an alabaster jar of very expensive ointment, and she poured it on his head as he sat at the table."},{"v":8,"t":"But when his disciples saw this, they were indignant, saying, “Why this waste?"},{"v":9,"t":"For this ointment might have been sold for much and given to the poor.”"},{"v":10,"t":"However, knowing this, Jesus said to them, “Why do you trouble the woman? She has done a good work for me."},{"v":11,"t":"For you always have the poor with you, but you don’t always have me."},{"v":12,"t":"For in pouring this ointment on my body, she did it to prepare me for burial."},{"v":13,"t":"Most certainly I tell you, wherever this Good News is preached in the whole world, what this woman has done will also be spoken of as a memorial of her.”"},{"v":14,"t":"Then one of the twelve, who was called Judas Iscariot, went to the chief priests"},{"v":15,"t":"and said, “What are you willing to give me if I deliver him to you?” So they weighed out for him thirty pieces of silver."},{"v":16,"t":"From that time he sought opportunity to betray him."},{"v":17,"t":"Now on the first day of unleavened bread, the disciples came to Jesus, saying to him, “Where do you want us to prepare for you to eat the Passover?”"},{"v":18,"t":"He said, “Go into the city to a certain person, and tell him, ‘The Teacher says, “My time is at hand. I will keep the Passover at your house with my disciples.”’”"},{"v":19,"t":"The disciples did as Jesus commanded them, and they prepared the Passover."},{"v":20,"t":"Now when evening had come, he was reclining at the table with the twelve disciples."},{"v":21,"t":"As they were eating, he said, “Most certainly I tell you that one of you will betray me.”"},{"v":22,"t":"They were exceedingly sorrowful, and each began to ask him, “It isn’t me, is it, Lord?”"},{"v":23,"t":"He answered, “He who dipped his hand with me in the dish will betray me."},{"v":24,"t":"The Son of Man goes even as it is written of him, but woe to that man through whom the Son of Man is betrayed! It would be better for that man if he had not been born.”"},{"v":25,"t":"Judas, who betrayed him, answered, “It isn’t me, is it, Rabbi?” He said to him, “You said it.”"},{"v":26,"t":"As they were eating, Jesus took bread, gave thanks for it, and broke it. He gave to the disciples and said, “Take, eat; this is my body.”"},{"v":27,"t":"He took the cup, gave thanks, and gave to them, saying, “All of you drink it,"},{"v":28,"t":"for this is my blood of the new covenant, which is poured out for many for the remission of sins."},{"v":29,"t":"But I tell you that I will not drink of this fruit of the vine from now on, until that day when I drink it anew with you in my Father’s Kingdom.”"},{"v":30,"t":"When they had sung a hymn, they went out to the Mount of Olives."},{"v":31,"t":"Then Jesus said to them, “All of you will be made to stumble because of me tonight, for it is written, ‘I will strike the shepherd, and the sheep of the flock will be scattered.’"},{"v":32,"t":"But after I am raised up, I will go before you into Galilee.”"},{"v":33,"t":"But Peter answered him, “Even if all will be made to stumble because of you, I will never be made to stumble.”"},{"v":34,"t":"Jesus said to him, “Most certainly I tell you that tonight, before the rooster crows, you will deny me three times.”"},{"v":35,"t":"Peter said to him, “Even if I must die with you, I will not deny you.” All of the disciples also said likewise."},{"v":36,"t":"Then Jesus came with them to a place called Gethsemane, and said to his disciples, “Sit here, while I go there and pray.”"},{"v":37,"t":"He took with him Peter and the two sons of Zebedee, and began to be sorrowful and severely troubled."},{"v":38,"t":"Then Jesus said to them, “My soul is exceedingly sorrowful, even to death. Stay here and watch with me.”"},{"v":39,"t":"He went forward a little, fell on his face, and prayed, saying, “My Father, if it is possible, let this cup pass away from me; nevertheless, not what I desire, but what you desire.”"},{"v":40,"t":"He came to the disciples and found them sleeping, and said to Peter, “What, couldn’t you watch with me for one hour?"},{"v":41,"t":"Watch and pray, that you don’t enter into temptation. The spirit indeed is willing, but the flesh is weak.”"},{"v":42,"t":"Again, a second time he went away and prayed, saying, “My Father, if this cup can’t pass away from me unless I drink it, your desire be done.”"},{"v":43,"t":"He came again and found them sleeping, for their eyes were heavy."},{"v":44,"t":"He left them again, went away, and prayed a third time, saying the same words."},{"v":45,"t":"Then he came to his disciples and said to them, “Are you still sleeping and resting? Behold, the hour is at hand, and the Son of Man is betrayed into the hands of sinners."},{"v":46,"t":"Arise, let’s be going. Behold, he who betrays me is at hand.”"},{"v":47,"t":"While he was still speaking, behold, Judas, one of the twelve, came, and with him a great multitude with swords and clubs, from the chief priests and elders of the people."},{"v":48,"t":"Now he who betrayed him had given them a sign, saying, “Whoever I kiss, he is the one. Seize him.”"},{"v":49,"t":"Immediately he came to Jesus, and said, “Greetings, Rabbi!” and kissed him."},{"v":50,"t":"Jesus said to him, “Friend, why are you here?” Then they came and laid hands on Jesus, and took him."},{"v":51,"t":"Behold, one of those who were with Jesus stretched out his hand and drew his sword, and struck the servant of the high priest, and cut off his ear."},{"v":52,"t":"Then Jesus said to him, “Put your sword back into its place, for all those who take the sword will die by the sword."},{"v":53,"t":"Or do you think that I couldn’t ask my Father, and he would even now send me more than twelve legions of angels?"},{"v":54,"t":"How then would the Scriptures be fulfilled that it must be so?”"},{"v":55,"t":"In that hour Jesus said to the multitudes, “Have you come out as against a robber with swords and clubs to seize me? I sat daily in the temple teaching, and you didn’t arrest me."},{"v":56,"t":"But all this has happened that the Scriptures of the prophets might be fulfilled.” Then all the disciples left him and fled."},{"v":57,"t":"Those who had taken Jesus led him away to Caiaphas the high priest, where the scribes and the elders were gathered together."},{"v":58,"t":"But Peter followed him from a distance to the court of the high priest, and entered in and sat with the officers, to see the end."},{"v":59,"t":"Now the chief priests, the elders, and the whole council sought false testimony against Jesus, that they might put him to death,"},{"v":60,"t":"and they found none. Even though many false witnesses came forward, they found none. But at last two false witnesses came forward"},{"v":61,"t":"and said, “This man said, ‘I am able to destroy the temple of God, and to build it in three days.’”"},{"v":62,"t":"The high priest stood up and said to him, “Have you no answer? What is this that these testify against you?”"},{"v":63,"t":"But Jesus stayed silent. The high priest answered him, “I adjure you by the living God that you tell us whether you are the Christ, the Son of God.”"},{"v":64,"t":"Jesus said to him, “You have said so. Nevertheless, I tell you, after this you will see the Son of Man sitting at the right hand of Power, and coming on the clouds of the sky.”"},{"v":65,"t":"Then the high priest tore his clothing, saying, “He has spoken blasphemy! Why do we need any more witnesses? Behold, now you have heard his blasphemy."},{"v":66,"t":"What do you think?” They answered, “He is worthy of death!”"},{"v":67,"t":"Then they spat in his face and beat him with their fists, and some slapped him,"},{"v":68,"t":"saying, “Prophesy to us, you Christ! Who hit you?”"},{"v":69,"t":"Now Peter was sitting outside in the court, and a maid came to him, saying, “You were also with Jesus, the Galilean!”"},{"v":70,"t":"But he denied it before them all, saying, “I don’t know what you are talking about.”"},{"v":71,"t":"When he had gone out onto the porch, someone else saw him and said to those who were there, “This man also was with Jesus of Nazareth.”"},{"v":72,"t":"Again he denied it with an oath, “I don’t know the man.”"},{"v":73,"t":"After a little while those who stood by came and said to Peter, “Surely you are also one of them, for your speech makes you known.”"},{"v":74,"t":"Then he began to curse and to swear, “I don’t know the man!” Immediately the rooster crowed."},{"v":75,"t":"Peter remembered the word which Jesus had said to him, “Before the rooster crows, you will deny me three times.” Then he went out and wept bitterly."}],"hr":[{"v":1,"t":"I kad Isus završi sve te besjede, reče svojim učenicima:"},{"v":2,"t":"“Znate da je za dva dana Pasha, i Sin Čovječji predaje se da se razapne.”"},{"v":3,"t":"Uto se sabraše glavari svećenički i starješine narodne u dvoru velikoga svećenika imenom Kajfe"},{"v":4,"t":"i zaključiše Isusa na prijevaru uhvatiti i ubiti."},{"v":5,"t":"Jer se govorilo: “Nikako ne o Blagdanu da ne nastane pobuna u narodu.”"},{"v":6,"t":"Kad je Isus bio u Betaniji, u kući Šimuna Gubavca,"},{"v":7,"t":"pristupi mu neka žena s alabastrenom posudicom skupocjene pomasti i polije ga po glavi, dok je on bio za stolom."},{"v":8,"t":"Vidjevši to, učenici negodovahu: “Čemu ta rasipnost?"},{"v":9,"t":"Moglo se to skupo prodati i dati siromasima.”"},{"v":10,"t":"Zapazio to Isus pa im reče: “Što dodijavate ženi? Dobro djelo učini prema meni."},{"v":11,"t":"Ta siromaha svagda imate uza se, a mene nemate svagda."},{"v":12,"t":"Izlila je tu pomast na moje tijelo - za ukop mi to učini."},{"v":13,"t":"Zaista, kažem vam, gdje se god bude propovijedalo ovo evanđelje, po svem svijetu, navješćivat će se i ovo što ona učini - njoj na spomen.”"},{"v":14,"t":"Tada jedan od dvanaestorice, zvan Juda Iškariotski, pođe glavarima svećeničkim"},{"v":15,"t":"i reče: “Što ćete mi dati i ja ću vam ga predati.” A oni mu odmjeriše trideset srebrnjaka."},{"v":16,"t":"Otada je tražio priliku da ga preda."},{"v":17,"t":"Prvoga dana Beskvasnih kruhova pristupiše učenici Isusu i upitaše: “Gdje hoćeš da ti pripravimo te blaguješ pashu?”"},{"v":18,"t":"On reče: “Idite u grad tomu i tomu i recite mu: 'Učitelj veli: Vrijeme je moje blizu, kod tebe slavim pashu sa svojim učenicima.'”"},{"v":19,"t":"I učine učenici kako im naredi Isus i priprave pashu."},{"v":20,"t":"Uvečer bijaše Isus za stolom s dvanaestoricom."},{"v":21,"t":"I dok su blagovali, reče: “Zaista, kažem vam, jedan će me od vas izdati.”"},{"v":22,"t":"Silno ožalošćeni, stanu mu jedan za drugim govoriti: “Da nisam ja, Gospodine?”"},{"v":23,"t":"On odgovori: “Onaj koji umoči sa mnom ruku u zdjelu, taj će me izdati."},{"v":24,"t":"Sin Čovječji, istina, odlazi kako je o njemu pisano, ali jao čovjeku onomu koji predaje Sina Čovječjega. Tomu bi čovjeku bolje bilo da se ni rodio nije.”"},{"v":25,"t":"A Juda, izdajnik, prihvati i reče: “Da nisam ja, učitelju?” Reče mu: “Ti kaza.”"},{"v":26,"t":"I dok su blagovali, uze Isus kruh, izreče blagoslov pa razlomi, dade svojim učenicima i reče: “Uzmite i jedite! Ovo je tijelo moje!”"},{"v":27,"t":"I uze čašu, zahvali i dade im govoreći: “Pijte iz nje svi!"},{"v":28,"t":"Ovo je krv moja, krv Saveza koja se za mnoge prolijeva na otpuštenje grijeha."},{"v":29,"t":"A kažem vam: ne, neću od sada piti od ovog roda trsova do onoga dana kad ću ga - novoga - s vama piti u kraljevstvu Oca svojega.”"},{"v":30,"t":"Otpjevavši hvalospjeve, zaputiše se prema Maslinskoj gori."},{"v":31,"t":"Tada im reče Isus: “Svi ćete se vi još ove noći sablazniti o mene. Ta pisano je: Udarit će pastira i stado će se razbjeći."},{"v":32,"t":"Ali kad uskrsnem, ići ću pred vama u Galileju.'"},{"v":33,"t":"Nato će mu Petar: “Ako se i svi sablazne o tebe, ja se nikada neću!”"},{"v":34,"t":"Reče mu Isus: “Zaista, kažem ti, još ove noći, prije negoli se pijetao oglasi, triput ćeš me zatajiti!”"},{"v":35,"t":"Kaže mu Petar: “Bude li trebalo i umrijeti s tobom, ne, neću te zatajiti.” Tako rekoše i svi učenici."},{"v":36,"t":"Tada dođe Isus s njima u predio zvan Getsemani i kaže učenicima: “Sjednite ovdje dok ja odem onamo pomoliti se.”"},{"v":37,"t":"I povede sa sobom Petra i oba sina Zebedejeva. Spopade ga žalost i tjeskoba."},{"v":38,"t":"Tada im reče: “Duša mi je nasmrt žalosna. Ostanite ovdje i bdijte sa mnom!”"},{"v":39,"t":"I ode malo dalje, pade ničice moleći: “Oče moj! Ako je moguće, neka me mimoiđe ova čaša. Ali ne kako ja hoću, nego kako hoćeš ti.”"},{"v":40,"t":"I dođe učenicima i nađe ih pozaspale pa reče Petru: “Tako, zar niste mogli jedan sat probdjeti sa mnom?"},{"v":41,"t":"Bdijte i molite da ne padnete u napast! Duh je, istina, voljan, no tijelo je slabo.”"},{"v":42,"t":"Opet, po drugi put, ode i pomoli se: “Oče moj! Ako nije moguće da me čaša mine da je ne pijem, budi volja tvoja!”"},{"v":43,"t":"I ponovno dođe i nađe ih pozaspale, oči im se sklapale."},{"v":44,"t":"Opet ih ostavi, pođe i pomoli se po treći put ponavljajući iste riječi."},{"v":45,"t":"Tada dođe učenicima i reče im: “Samo spavajte i počivajte! Evo, približio se čas! Sin Čovječji predaje se u ruke grešničke!"},{"v":46,"t":"Ustanite, hajdemo! Evo, približio se moj izdajica.”"},{"v":47,"t":"Dok je on još govorio, gle, dođe Juda, jedan od dvanaestorice, i s njime silna svjetina s mačevima i toljagama poslana od glavara svećeničkih i starješina narodnih."},{"v":48,"t":"A izdajica im dao znak: “Koga poljubim, taj je, njega uhvatite!”"},{"v":49,"t":"I odmah pristupi Isusu i reče: “Zdravo, Učitelju!” I poljubi ga."},{"v":50,"t":"A Isus mu reče: “Prijatelju, zašto ti ovdje!” Tada pristupe, podignu ruke na Isusa i uhvate ga."},{"v":51,"t":"I gle, jedan od onih koji bijahu s Isusom maši se rukom, trgnu mač, udari slugu velikoga svećenika i odsiječe mu uho."},{"v":52,"t":"Kaže mu tada Isus: “Vrati mač na njegovo mjesto jer svi koji se mača laćaju od mača i ginu."},{"v":53,"t":"Ili zar misliš da ja ne mogu zamoliti Oca svojega i eto umah uza me više od dvanaest legija anđela?"},{"v":54,"t":"No kako bi se onda ispunila Pisma da tako mora biti?”"},{"v":55,"t":"U taj čas reče Isus svjetini: “Kao na razbojnika iziđoste s mačevima i toljagama da me uhvatite? Danomice sjeđah u Hramu naučavajući i ne uhvatiste me.”"},{"v":56,"t":"A sve se to dogodilo da se ispune Pisma proročka. Tada ga svi učenici ostave i pobjegnu."},{"v":57,"t":"Nato uhvatiše Isusa i odvedoše ga velikomu svećeniku Kajfi, kod kojega se sabraše pismoznanci i starješine."},{"v":58,"t":"A Petar je išao za njim izdaleka do dvora velikog svećenika; i ušavši unutra, sjedne sa stražarima da vidi svršetak."},{"v":59,"t":"A glavari svećenički i cijelo Vijeće tražili su kakvo lažno svjedočanstvo protiv Isusa da bi ga mogli pogubiti."},{"v":60,"t":"Ali ne nađoše premda pristupiše mnogi lažni svjedoci. Napokon pristupe dvojica"},{"v":61,"t":"i reknu: “Ovaj reče: 'Mogu razvaliti Hram Božji i za tri ga dana sagraditi.'”"},{"v":62,"t":"Usta nato veliki svećenik i reče mu: “Zar ništa ne odgovaraš? Što to ovi protiv tebe svjedoče?”"},{"v":63,"t":"Isus je šutio. Reče mu veliki svećenik: “Zaklinjem te Bogom živim: Kaži nam jesi li ti Krist, Sin Božji?”"},{"v":64,"t":"Reče mu Isus: “Ti kaza! Štoviše, kažem vam: Odsada ćete gledati Sina Čovječjega gdje sjedi zdesna Sile i dolazi na oblacima nebeskim.”"},{"v":65,"t":"Nato veliki svećenik razdrije haljine govoreći: “Pohulio je! Što nam još trebaju svjedoci! Evo, sada ste čuli hulu!"},{"v":66,"t":"Što vam se čini?” Oni odgovoriše: “Smrt zaslužuje!”"},{"v":67,"t":"Tada su mu pljuvali u lice i udarali ga, a drugi ga pljuskali"},{"v":68,"t":"govoreći: “Proreci nam, Kriste, tko te udario?”"},{"v":69,"t":"A Petar je sjedio vani u dvorištu. I pristupi mu jedna sluškinja govoreći: “I ti bijaše s Isusom Galilejcem.”"},{"v":70,"t":"On pred svima zanijeka: “Ne znam što govoriš.”"},{"v":71,"t":"Kad iziđe u predvorje, spazi ga druga i kaže nazočnima: “Ovaj bijaše s Isusom Nazarećaninom.”"},{"v":72,"t":"On opet zanijeka sa zakletvom: “Ne znam toga čovjeka.”"},{"v":73,"t":"Malo zatim nazočni pristupiše Petru i rekoše: “Doista, i ti si od njih! Ta govor te tvoj izdaje!”"},{"v":74,"t":"On se tada stane zaklinjati i preklinjati: “Ne znam toga čovjeka.” I odmah se oglasi pijetao."},{"v":75,"t":"I spomenu se Petar riječi koju mu Isus reče: “Prije nego se pijetao oglasi, triput ćeš me zatajiti.” I iziđe te gorko zaplaka."}]},"27":{"fa":[{"v":1,"t":"و چون صبح شد، همه روسای کهنه ومشایخ قوم بر عیسی شورا کردند که اورا هلاک سازند."},{"v":2,"t":"پس او را بند نهاده، بردند و به پنطیوس پیلاطس والی تسلیم نمودند."},{"v":3,"t":"در آن هنگام، چون یهودا تسلیم‌کننده او دید که بر او فتوا دادند، پشیمان شده، سی پاره نقره را به روسای کهنه و مشایخ رد کرده،"},{"v":4,"t":"گفت: «گناه کردم که خون بیگناهی را تسلیم نمودم.» گفتند: «ما را چه، خود دانی!»"},{"v":5,"t":"پس آن نقره را درهیکل انداخته، روانه شد و رفته خود را خفه نمود."},{"v":6,"t":"اما روسای کهنه نقره را بر داشته، گفتند: «انداختن این در بیت‌المال جایز نیست زیرا خونبها است.»"},{"v":7,"t":"پس شورا نموده، به آن مبلغ، مزرعه کوزه‌گر را بجهت مقبره غرباءخریدند."},{"v":8,"t":"از آن جهت، آن مزرعه تا امروزبحقل الدم مشهور است."},{"v":9,"t":"آنگاه سخنی که به زبان ارمیای نبی گفته شده بود تمام گشت که «سی پاره نقره را برداشتند، بهای آن قیمت کرده شده‌ای که بعضی از بنی‌اسرائیل بر او قیمت گذاردند."},{"v":10,"t":"و آنها را بجهت مزرعه کوزه‌گر دادند، چنانکه خداوند به من گفت.»"},{"v":11,"t":"اما عیسی در حضور والی ایستاده بود. پس والی از او پرسیده، گفت: «آیا تو پادشاه یهودهستی؟» عیسی بدو گفت: «تو می‌گویی!»"},{"v":12,"t":"وچون روسای کهنه و مشایخ از او شکایت می‌کردند، هیچ جواب نمی داد."},{"v":13,"t":"پس پیلاطس وی را گفت: «نمی شنوی چقدر بر تو شهادت می‌دهند؟»"},{"v":14,"t":"اما در جواب وی، یک سخن هم نگفت، بقسمی که والی بسیار متعجب شد."},{"v":15,"t":"و در هر عیدی، رسم والی این بود که یک زندانی، هر‌که را می‌خواستند، برای جماعت آزاد می‌کرد."},{"v":16,"t":"و در آن وقت، زندانی مشهور، برابا نام داشت."},{"v":17,"t":"پس چون مردم جمع شدند، پیلاطس ایشان را گفت: «که را می‌خواهید برای شما آزاد کنم؟ برابا یا عیسی مشهور به مسیح را؟»"},{"v":18,"t":"زیرا که دانست او را از حسد تسلیم کرده بودند."},{"v":19,"t":"چون بر مسند نشسته بود، زنش نزد اوفرستاده، گفت: «با این مرد عادل تو را کاری نباشد، زیرا که امروز در خواب درباره او زحمت بسیار بردم.»"},{"v":20,"t":"اما روسای کهنه و مشایخ، قوم را بر این ترغیب نمودند که برابا را بخواهند و عیسی راهلاک سازند."},{"v":21,"t":"پس والی بدیشان متوجه شده، گفت: «کدام‌یک از این دو نفر را می‌خواهیدبجهت شما رها کنم؟ گفتند: «برابا را.»"},{"v":22,"t":"پیلاطس بدیشان گفت: «پس با عیسی مشهور به مسیح چه کنم؟» جمیع گفتند: «مصلوب شود!»"},{"v":23,"t":"والی گفت: «چرا؟ چه بدی کرده است؟» ایشان بیشترفریاد زده، گفتند: «مصلوب شود!»"},{"v":24,"t":"چون پیلاطس دید که ثمری ندارد بلکه آشوب زیاده می‌گردد، آب طلبیده، پیش مردم دست خود راشسته گفت: «من بری هستم از خون این شخص عادل. شما ببینید.»"},{"v":25,"t":"تمام قوم در جواب گفتند: «خون او بر ما و فرزندان ما باد!»"},{"v":26,"t":"آنگاه برابا رابرای ایشان آزاد کرد و عیسی را تازیانه زده، سپرد تا او را مصلوب کنند."},{"v":27,"t":"آنگاه سپاهیان والی، عیسی را به دیوانخانه برده، تمامی فوج را گرد وی فراهم آوردند."},{"v":28,"t":"واو را عریان ساخته، لباس قرمزی بدو پوشانیدند،"},{"v":29,"t":"و تاجی از خار بافته، بر سرش گذاردند و نی بدست راست او دادند و پیش وی زانو زده، استهزاکنان او را می‌گفتند: «سلام‌ای پادشاه یهود!»"},{"v":30,"t":"و آب دهان بر وی افکنده، نی را گرفته بر سرش می‌زدند."},{"v":31,"t":"و بعد از آنکه او را استهزاکرده بودند، آن لباس را از وی کنده، جامه خودش را پوشانیدند و او را بجهت مصلوب نمودن بیرون بردند."},{"v":32,"t":"و چون بیرون می‌رفتند، شخصی قیروانی شمعون نام را یافته، او را بجهت بردن صلیب مجبور کردند."},{"v":33,"t":"و چون به موضعی که به جلجتایعنی کاسه سر مسمی بود رسیدند،"},{"v":34,"t":"سرکه ممزوج به مر بجهت نوشیدن بدو دادند. اما چون چشید، نخواست که بنوشد."},{"v":35,"t":"پس او را مصلوب نموده، رخت او راتقسیم نمودند و بر آنها قرعه انداختند تا آنچه به زبان نبی گفته شده بود تمام شود که «رخت مرا درمیان خود تقسیم کردند و بر لباس من قرعه انداختند.»"},{"v":36,"t":"و در آنجا به نگاهبانی او نشستند."},{"v":37,"t":"و تقصیر نامه او را نوشته، بالای سرش آویختند که «این است عیسی، پادشاه یهود!»"},{"v":38,"t":"آنگاه دو دزد یکی بر دست راست و دیگری برچپش با وی مصلوب شدند."},{"v":39,"t":"و راهگذاران سرهای خود را جنبانیده، کفر گویان"},{"v":40,"t":"می‌گفتند: «ای کسی‌که هیکل را خراب می‌کنی و در سه روزآن را می‌سازی، خود را نجات ده. اگر پسر خداهستی، از صلیب فرود بیا!»"},{"v":41,"t":"همچنین نیزروسای کهنه با کاتبان و مشایخ استهزاکنان می‌گفتند:"},{"v":42,"t":"«دیگران را نجات داد، اما نمی تواندخود را برهاند. اگر پادشاه اسرائیل است، اکنون ازصلیب فرود آید تا بدو ایمان آوریم!"},{"v":43,"t":"بر خداتوکل نمود، اکنون او را نجات دهد، اگر بدورغبت دارد زیرا گفت پسر خدا هستم!»"},{"v":44,"t":"وهمچنین آن دو دزد نیز که با وی مصلوب بودند، او را دشنام می‌دادند."},{"v":45,"t":"و از ساعت ششم تا ساعت نهم، تاریکی تمام زمین را فرو گرفت."},{"v":46,"t":"و نزدیک به ساعت نهم، عیسی به آواز بلند صدا زده گفت: «ایلی ایلی لما سبقتنی.» یعنی الهی الهی مرا چرا ترک کردی."},{"v":47,"t":"اما بعضی از حاضرین چون این را شنیدند، گفتند که او الیاس را می‌خواند."},{"v":48,"t":"در ساعت یکی از آن میان دویده، اسفنجی را گرفت و آن را پر ازسرکه کرده، بر سر نی گذارد و نزد او داشت تابنوشد."},{"v":49,"t":"و دیگران گفتند: «بگذار تا ببینیم که آیاالیاس می‌آید او را برهاند.»"},{"v":50,"t":"عیسی باز به آوازبلند صیحه زده، روح را تسلیم نمود."},{"v":51,"t":"که ناگاه پرده هیکل از سر تا پا دو پاره شد و زمین متزلزل وسنگها شکافته گردید،"},{"v":52,"t":"و قبرها گشاده شد وبسیاری از بدنهای مقدسین که آرامیده بودندبرخاستند،"},{"v":53,"t":"و بعد از برخاستن وی، از قبوربرآمده، به شهر مقدس رفتند و بر بسیاری ظاهرشدند."},{"v":54,"t":"اما یوزباشی و رفقایش که عیسی رانگاهبانی می‌کردند، چون زلزله و این وقایع رادیدند، بینهایت ترسان شده، گفتند: «فی الواقع این شخص پسر خدا بود.»"},{"v":55,"t":"و در آنجا زنان بسیاری که از جلیل در عقب عیسی آمده بودند تا او راخدمت کنند، از دور نظاره می‌کردند،"},{"v":56,"t":"که از آن جمله، مریم مجدلیه بود و مریم مادر یعقوب ویوشاء و مادر پسران زبدی."},{"v":57,"t":"اما چون وقت عصر رسید، شخصی دولتمند از اهل رامه، یوسف نام که او نیز ازشاگردان عیسی بود آمد،"},{"v":58,"t":"و نزد پیلاطس رفته، جسد عیسی را خواست. آنگاه پیلاطس فرمان داد که داده شود."},{"v":59,"t":"پس یوسف جسد را برداشته، آن را در کتان پاک پیچیده،"},{"v":60,"t":"او را در قبری نو که برای خود از سنگ تراشیده بود، گذارد و سنگی بزرگ بر سر آن غلطانیده، برفت."},{"v":61,"t":"و مریم مجدلیه و مریم دیگر در آنجا، در مقابل قبرنشسته بودند."},{"v":62,"t":"و در فردای آن روز که بعد از روز تهیه بودروسای کهنه و فریسیان نزد پیلاطس جمع شده،"},{"v":63,"t":"گفتند: «ای آقا ما را یاد است که آن گمراه‌کننده وقتی که زنده بود گفت: “بعد از سه روزبرمی خیزم.”"},{"v":64,"t":"پس بفرما قبر را تا سه روزنگاهبانی کنند مبادا شاگردانش در شب آمده، اورا بدزدند و به مردم گویند که از مردگان برخاسته است و گمراهی آخر، از اول بدتر شود.»"},{"v":65,"t":"پیلاطس بدیشان فرمود: «شما کشیکچیان دارید. بروید چنانکه دانید، محافظت کنید.»"},{"v":66,"t":"پس رفتند و سنگ را مختوم ساخته، قبر را باکشیکچیان محافظت نمودند."}],"en":[{"v":1,"t":"Now when morning had come, all the chief priests and the elders of the people took counsel against Jesus to put him to death."},{"v":2,"t":"They bound him, led him away, and delivered him up to Pontius Pilate, the governor."},{"v":3,"t":"Then Judas, who betrayed him, when he saw that Jesus was condemned, felt remorse, and brought back the thirty pieces of silver to the chief priests and elders,"},{"v":4,"t":"saying, “I have sinned in that I betrayed innocent blood.” But they said, “What is that to us? You see to it.”"},{"v":5,"t":"He threw down the pieces of silver in the sanctuary and departed. Then he went away and hanged himself."},{"v":6,"t":"The chief priests took the pieces of silver and said, “It’s not lawful to put them into the treasury, since it is the price of blood.”"},{"v":7,"t":"They took counsel, and bought the potter’s field with them to bury strangers in."},{"v":8,"t":"Therefore that field has been called “The Field of Blood” to this day."},{"v":9,"t":"Then that which was spoken through Jeremiah the prophet was fulfilled, saying, “They took the thirty pieces of silver, the price of him upon whom a price had been set, whom some of the children of Israel priced,"},{"v":10,"t":"and they gave them for the potter’s field, as the Lord commanded me.”"},{"v":11,"t":"Now Jesus stood before the governor; and the governor asked him, saying, “Are you the King of the Jews?” Jesus said to him, “So you say.”"},{"v":12,"t":"When he was accused by the chief priests and elders, he answered nothing."},{"v":13,"t":"Then Pilate said to him, “Don’t you hear how many things they testify against you?”"},{"v":14,"t":"He gave him no answer, not even one word, so that the governor marveled greatly."},{"v":15,"t":"Now at the feast the governor was accustomed to release to the multitude one prisoner whom they desired."},{"v":16,"t":"They had then a notable prisoner called Barabbas."},{"v":17,"t":"When therefore they were gathered together, Pilate said to them, “Whom do you want me to release to you? Barabbas, or Jesus who is called Christ?”"},{"v":18,"t":"For he knew that because of envy they had delivered him up."},{"v":19,"t":"While he was sitting on the judgment seat, his wife sent to him, saying, “Have nothing to do with that righteous man, for I have suffered many things today in a dream because of him.”"},{"v":20,"t":"Now the chief priests and the elders persuaded the multitudes to ask for Barabbas and destroy Jesus."},{"v":21,"t":"But the governor answered them, “Which of the two do you want me to release to you?” They said, “Barabbas!”"},{"v":22,"t":"Pilate said to them, “What then shall I do to Jesus who is called Christ?” They all said to him, “Let him be crucified!”"},{"v":23,"t":"But the governor said, “Why? What evil has he done?” But they cried out exceedingly, saying, “Let him be crucified!”"},{"v":24,"t":"So when Pilate saw that nothing was being gained, but rather that a disturbance was starting, he took water and washed his hands before the multitude, saying, “I am innocent of the blood of this righteous person. You see to it.”"},{"v":25,"t":"All the people answered, “May his blood be on us and on our children!”"},{"v":26,"t":"Then he released Barabbas to them, but Jesus he flogged and delivered to be crucified."},{"v":27,"t":"Then the governor’s soldiers took Jesus into the Praetorium, and gathered the whole garrison together against him."},{"v":28,"t":"They stripped him and put a scarlet robe on him."},{"v":29,"t":"They braided a crown of thorns and put it on his head, and a reed in his right hand; and they kneeled down before him and mocked him, saying, “Hail, King of the Jews!”"},{"v":30,"t":"They spat on him, and took the reed and struck him on the head."},{"v":31,"t":"When they had mocked him, they took the robe off him, and put his clothes on him, and led him away to crucify him."},{"v":32,"t":"As they came out, they found a man of Cyrene, Simon by name, and they compelled him to go with them, that he might carry his cross."},{"v":33,"t":"When they came to a place called “Golgotha”, that is to say, “The place of a skull,”"},{"v":34,"t":"they gave him sour wine to drink mixed with gall. When he had tasted it, he would not drink."},{"v":35,"t":"When they had crucified him, they divided his clothing among them, casting lots,"},{"v":36,"t":"and they sat and watched him there."},{"v":37,"t":"They set up over his head the accusation against him written, “THIS IS JESUS, THE KING OF THE JEWS.”"},{"v":38,"t":"Then there were two robbers crucified with him, one on his right hand and one on the left."},{"v":39,"t":"Those who passed by blasphemed him, wagging their heads"},{"v":40,"t":"and saying, “You who destroy the temple and build it in three days, save yourself! If you are the Son of God, come down from the cross!”"},{"v":41,"t":"Likewise the chief priests also mocking with the scribes, the Pharisees, and the elders, said,"},{"v":42,"t":"“He saved others, but he can’t save himself. If he is the King of Israel, let him come down from the cross now, and we will believe in him."},{"v":43,"t":"He trusts in God. Let God deliver him now, if he wants him; for he said, ‘I am the Son of God.’”"},{"v":44,"t":"The robbers also who were crucified with him cast on him the same reproach."},{"v":45,"t":"Now from the sixth hour there was darkness over all the land until the ninth hour."},{"v":46,"t":"About the ninth hour Jesus cried with a loud voice, saying, “Eli, Eli, lima sabachthani?” That is, “My God, my God, why have you forsaken me?”"},{"v":47,"t":"Some of them who stood there, when they heard it, said, “This man is calling Elijah.”"},{"v":48,"t":"Immediately one of them ran and took a sponge, filled it with vinegar, put it on a reed, and gave him a drink."},{"v":49,"t":"The rest said, “Let him be. Let’s see whether Elijah comes to save him.”"},{"v":50,"t":"Jesus cried again with a loud voice, and yielded up his spirit."},{"v":51,"t":"Behold, the veil of the temple was torn in two from the top to the bottom. The earth quaked and the rocks were split."},{"v":52,"t":"The tombs were opened, and many bodies of the saints who had fallen asleep were raised;"},{"v":53,"t":"and coming out of the tombs after his resurrection, they entered into the holy city and appeared to many."},{"v":54,"t":"Now the centurion and those who were with him watching Jesus, when they saw the earthquake and the things that were done, were terrified, saying, “Truly this was the Son of God!”"},{"v":55,"t":"Many women were there watching from afar, who had followed Jesus from Galilee, serving him."},{"v":56,"t":"Among them were Mary Magdalene, Mary the mother of James and Joses, and the mother of the sons of Zebedee."},{"v":57,"t":"When evening had come, a rich man from Arimathaea named Joseph, who himself was also Jesus’ disciple, came."},{"v":58,"t":"This man went to Pilate and asked for Jesus’ body. Then Pilate commanded the body to be given up."},{"v":59,"t":"Joseph took the body and wrapped it in a clean linen cloth"},{"v":60,"t":"and laid it in his own new tomb, which he had cut out in the rock. Then he rolled a large stone against the door of the tomb, and departed."},{"v":61,"t":"Mary Magdalene was there, and the other Mary, sitting opposite the tomb."},{"v":62,"t":"Now on the next day, which was the day after the Preparation Day, the chief priests and the Pharisees were gathered together to Pilate,"},{"v":63,"t":"saying, “Sir, we remember what that deceiver said while he was still alive: ‘After three days I will rise again.’"},{"v":64,"t":"Command therefore that the tomb be made secure until the third day, lest perhaps his disciples come at night and steal him away, and tell the people, ‘He is risen from the dead;’ and the last deception will be worse than the first.”"},{"v":65,"t":"Pilate said to them, “You have a guard. Go, make it as secure as you can.”"},{"v":66,"t":"So they went with the guard and made the tomb secure, sealing the stone."}],"hr":[{"v":1,"t":"A kad objutri, svi su glavari svećenički i starješine narodne održali vijećanje protiv Isusa da ga pogube."},{"v":2,"t":"I svezana ga odveli i predali upravitelju Pilatu."},{"v":3,"t":"Kada Juda, njegov izdajica, vidje da je Isus osuđen, pokaja se i vrati trideset srebrnjaka glavarima svećeničkim i starješinama"},{"v":4,"t":"govoreći: “Sagriješih predavši krv nedužnu!” Odgovoriše: “Što se to nas tiče? To je tvoja stvar!”"},{"v":5,"t":"I bacivši srebrnjake u Hram, ode te se objesi."},{"v":6,"t":"Glavari svećenički uzeše srebrnjake i rekoše:"},{"v":7,"t":"“Nije dopušteno staviti ih u hramsku riznicu jer su krvarina.” Posavjetuju se i kupe za njih lončarovu njivu za ukop stranaca."},{"v":8,"t":"Stoga se ona njiva zove “Krvava njiva” sve do danas."},{"v":9,"t":"Tada se ispuni što je rečeno po proroku Jeremiji: Uzeše trideset srebrnjaka - cijenu Neprocjenjivoga kojega procijeniše sinovi Izraelovi -"},{"v":10,"t":"i dadoše ih za njivu lončarovu kako mi naredi Gospodin."},{"v":11,"t":"Dovedoše dakle Isusa pred upravitelja. Upita ga upravitelj: “Ti li si kralj židovski?” On odgovori: “Ti kažeš.”"},{"v":12,"t":"I dok su ga glavari svećenički i starješine narodne optuživale, ništa nije odgovarao."},{"v":13,"t":"Tada mu reče Pilat: “Ne čuješ li što sve protiv tebe svjedoče?”"},{"v":14,"t":"I ne odgovori mu ni na jednu riječ te se upravitelj silno čudio."},{"v":15,"t":"A o Blagdanu upravitelj je običavao svjetini pustiti jednoga uznika, koga bi već htjeli."},{"v":16,"t":"Tada upravo bijaše u njih poznati uznik zvani Baraba."},{"v":17,"t":"Kad se dakle sabraše, reče im Pilat: “Koga hoćete da vam pustim: Barabu ili Isusa koji se zove Krist?”"},{"v":18,"t":"Znao je doista da ga predadoše iz zavisti."},{"v":19,"t":"Dok je sjedio na sudačkoj stolici, poruči nu njegova žena: “Mani se ti onoga pravednika jer sam danas u snu mnogo pretrpjela zbog njega.”"},{"v":20,"t":"Međutim, glavari svećenički i starješine nagovore svjetinu da zaište Barabu, a Isus da se pogubi."},{"v":21,"t":"Upita ih dakle upravitelj: “Kojega od ove dvojice hoćete da vam pustim?” A oni rekoše: “Barabu!”"},{"v":22,"t":"Kaže im Pilat: “Što dakle da učinim s Isusom koji se zove Krist?” Oni će: “Neka se razapne.”"},{"v":23,"t":"A on upita: “A što je zla učinio?” Vikahu još jače: “Neka se razapne!”"},{"v":24,"t":"Kad Pilat vidje da ništa ne koristi, nego da biva sve veći metež, uzme vodu i opere ruke pred svjetinom govoreći: “Nevin sam od krvi ove! Vi se pazite!”"},{"v":25,"t":"Sav narod nato odvrati: “Krv njegova na nas i na djecu našu!”"},{"v":26,"t":"Tada im pusti Barabu, a Isusa, izbičevana, preda da se razapne."},{"v":27,"t":"Onda vojnici upraviteljevi uvedoše Isusa u dvor upraviteljev i skupiše oko njega cijelu četu."},{"v":28,"t":"Svukoše ga pa zaogrnuše skrletnim plaštem."},{"v":29,"t":"Spletoše zatim vijenac od trnja i staviše mu na glavu, a tako i trsku u desnicu. Prigibajući pred njim koljena, izrugivahu ga: “Zdravo, kralju židovski!”"},{"v":30,"t":"Onda pljujući po njemu, uzimahu trsku i udarahu ga njome po glavi."},{"v":31,"t":"Pošto ga izrugaše, svukoše mu plašt, obukoše mu njegove haljine pa ga odvedoše da ga razapnu."},{"v":32,"t":"Izlazeći nađu nekoga čovjeka Cirenca, imenom Šimuna, i prisile ga da mu ponese križ."},{"v":33,"t":"I dođoše na mjesto zvano Golgota, to jest Lubanjsko mjesto,"},{"v":34,"t":"dadoše mu piti vino sa žuči pomiješano. I kad okusi, ne htjede piti."},{"v":35,"t":"A pošto ga razapeše, razdijeliše među se haljine njegove bacivši kocku."},{"v":36,"t":"I sjedeći ondje, čuvahu ga."},{"v":37,"t":"I staviše mu ponad glave krivicu napisanu: “Ovo je Isus, kralj židovski.”"},{"v":38,"t":"Tada razapeše s njime dva razbojnika, jednoga zdesna, drugoga slijeva."},{"v":39,"t":"A prolaznici su ga pogrđivali mašući glavama:"},{"v":40,"t":"“Ti koji razvaljuješ Hram i za tri ga dana sagradiš, spasi sam sebe! Ako si Sin Božji, siđi s križa!”"},{"v":41,"t":"Slično i glavari svećenički s pismoznancima i starješinama, rugajući se, govorahu:"},{"v":42,"t":"“Druge je spasio, sebe ne može spasiti! Kralj je Izraelov! Neka sada siđe s križa pa ćemo povjerovati u nj!"},{"v":43,"t":"Uzdao se u Boga! Neka ga sad izbavi ako mu omilje! Ta govorio je: 'Sin sam Božji!'”"},{"v":44,"t":"Tako ga vrijeđahu i s njim raspeti razbojnici."},{"v":45,"t":"Od šeste ure nasta tama po svoj zemlji - do ure devete."},{"v":46,"t":"O devetoj uri povika Isus iza glasa: “Eli, Eli, lema sabahtani?” To će reći: “Bože moj, Bože moj, zašto si me ostavio?”"},{"v":47,"t":"A neki od nazočnih, čuvši to, govorahu: “Ovaj zove Iliju.”"},{"v":48,"t":"I odmah pritrča jedan od njih, uze spužvu, natopi je octom, natakne je na trsku i pruži mu piti."},{"v":49,"t":"A ostali rekoše: “Pusti da vidimo hoće li doći Ilija da ga spasi.”"},{"v":50,"t":"A Isus opet povika iz glasa i ispusti duh."},{"v":51,"t":"I gle, zavjesa se hramska razdrije odozgor dodolje, nadvoje; zemlja se potrese, pećine se raspukoše,"},{"v":52,"t":"grobovi otvoriše i tjelesa mnogih svetih preminulih uskrsnuše"},{"v":53,"t":"te iziđoše iz grobova nakon njegova uskrsnuća, uđoše u sveti grad i pokazaše se mnogima."},{"v":54,"t":"A satnik i oni koji su s njime čuvali Isusa vidješe potres i što se zbiva, silno se prestrašiše i rekoše: “Uistinu, Sin Božji bijaše ovaj.”"},{"v":55,"t":"A bijahu ondje i izdaleka promatrahu mnoge žene što su iz Galileje išle za Isusom poslužujući mu;"},{"v":56,"t":"među njima Marija Magdalena i Marija, Jakovljeva i Josipova majka, i majka sinova Zebedejevih."},{"v":57,"t":"Uvečer dođe neki bogat čovjek iz Arimateje, imenom Josip, koji i sam bijaše učenik Isusov."},{"v":58,"t":"On pristupi Pilatu i zaiska tijelo Isusovo. Tada Pilat zapovjedi da mu se dadne."},{"v":59,"t":"Josip uze tijelo, povi ga u čisto platno"},{"v":60,"t":"i položi u svoj novi grob koji bijaše isklesao u stijeni. Dokotrlja velik kamen na grobna vrata i otiđe."},{"v":61,"t":"A bijahu ondje Marija Magdalena i druga Marija: sjedile su nasuprot grobu."},{"v":62,"t":"Sutradan, to jest dan nakon Priprave, sabraše se glavari svećenički i farizeji kod Pilata"},{"v":63,"t":"te mu rekoše: “Gospodaru, sjetismo se da onaj varalica još za života kaza: 'Nakon tri dana uskrsnut ću.'"},{"v":64,"t":"Zapovjedi dakle da se grob osigura sve do trećega dana da ne bi možda došli njegovi učenici, ukrali ga pa rekli narodu: 'Uskrsnuo je od mrtvih!' I bit će posljednja prijevara gora od prve.”"},{"v":65,"t":"Reče im Pilat: “Imate stražu! Idite i osigurajte kako znate!”"},{"v":66,"t":"Nato oni odu i osiguraju grob: zapečate kamen i postave stražu."}]},"28":{"fa":[{"v":1,"t":"و بعد از سبت، هنگام فجر، روز اول هفته، مریم مجدلیه و مریم دیگربجهت دیدن قبر‌آمدند."},{"v":2,"t":"که ناگاه زلزله‌ای عظیم حادث شد از آنرو که فرشته خداوند از آسمان نزول کرده، آمد و سنگ را از در قبر غلطانیده، برآن بنشست."},{"v":3,"t":"و صورت او مثل برق و لباسش چون برف سفید بود."},{"v":4,"t":"و از ترس او کشیکچیان به لرزه درآمده، مثل مرده گردیدند."},{"v":5,"t":"اما فرشته به زنان متوجه شده، گفت: شما ترسان مباشید!"},{"v":6,"t":"دراینجا نیست زیرا چنانکه گفته بود برخاسته است. بیایید جایی که خداوند خفته بود ملاحظه کنید،"},{"v":7,"t":"و به زودی رفته شاگردانش را خبر دهید که ازمردگان برخاسته است. اینک پیش از شما به جلیل می‌رود. در آنجا او را خواهید دید. اینک شما را گفتم.»"},{"v":8,"t":"پس، از قبر با ترس و خوشی عظیم به زودی روانه شده، رفتند تا شاگردان او را اطلاع دهند."},{"v":9,"t":"ودر هنگامی که بجهت اخبار شاگردان او می‌رفتند، ناگاه عیسی بدیشان برخورده، گفت: «سلام برشما باد!» پس پیش آمده، به قدمهای اوچسبیده، او را پرستش کردند."},{"v":10,"t":"آنگاه عیسی بدیشان گفت: «مترسید! رفته، برادرانم رابگویید که به جلیل بروند که در آنجا مرا خواهنددید.»"},{"v":11,"t":"و چون ایشان می‌رفتند، ناگاه بعضی ازکشیکچیان به شهر شده، روسای کهنه را از همه این وقایع مطلع ساختند."},{"v":12,"t":"ایشان با مشایخ جمع شده، شورا نمودند و نقره بسیار به سپاهیان داده،"},{"v":13,"t":"گفتند: «بگویید که شبانگاه شاگردانش آمده، وقتی که ما در خواب بودیم او را دزدیدند."},{"v":14,"t":"وهرگاه این سخن گوش زد والی شود، همانا ما او رابرگردانیم و شما را مطمئن سازیم.»"},{"v":15,"t":"ایشان پول را گرفته، چنانکه تعلیم یافتند کردند و این سخن تاامروز در میان یهود منتشر است."},{"v":16,"t":"اما یازده رسول به جلیل، بر کوهی که عیسی ایشان را نشان داده بود رفتند."},{"v":17,"t":"و چون او را دیدند، پرستش نمودند. لیکن بعضی شک کردند."},{"v":18,"t":"پس عیسی پیش آمده، بدیشان خطاب کرده، گفت: «تمامی قدرت در آسمان و بر زمین به من داده شده است."},{"v":19,"t":"پس رفته، همه امت‌ها را شاگرد سازید و ایشان رابه اسم اب و ابن و روح‌القدس تعمید دهید."},{"v":20,"t":"وایشان را تعلیم دهید که همه اموری را که به شما حکم کرده‌ام حفظ کنند. و اینک من هرروزه تا انقضای عالم همراه شما می‌باشم.» آمین."}],"en":[{"v":1,"t":"Now after the Sabbath, as it began to dawn on the first day of the week, Mary Magdalene and the other Mary came to see the tomb."},{"v":2,"t":"Behold, there was a great earthquake, for an angel of the Lord descended from the sky and came and rolled away the stone from the door and sat on it."},{"v":3,"t":"His appearance was like lightning, and his clothing white as snow."},{"v":4,"t":"For fear of him, the guards shook, and became like dead men."},{"v":5,"t":"The angel answered the women, “Don’t be afraid, for I know that you seek Jesus, who has been crucified."},{"v":6,"t":"He is not here, for he has risen, just like he said. Come, see the place where the Lord was lying."},{"v":7,"t":"Go quickly and tell his disciples, ‘He has risen from the dead, and behold, he goes before you into Galilee; there you will see him.’ Behold, I have told you.”"},{"v":8,"t":"They departed quickly from the tomb with fear and great joy, and ran to bring his disciples word."},{"v":9,"t":"As they went to tell his disciples, behold, Jesus met them, saying, “Rejoice!” They came and took hold of his feet, and worshiped him."},{"v":10,"t":"Then Jesus said to them, “Don’t be afraid. Go tell my brothers that they should go into Galilee, and there they will see me.”"},{"v":11,"t":"Now while they were going, behold, some of the guards came into the city and told the chief priests all the things that had happened."},{"v":12,"t":"When they were assembled with the elders and had taken counsel, they gave a large amount of silver to the soldiers,"},{"v":13,"t":"saying, “Say that his disciples came by night and stole him away while we slept."},{"v":14,"t":"If this comes to the governor’s ears, we will persuade him and make you free of worry.”"},{"v":15,"t":"So they took the money and did as they were told. This saying was spread abroad among the Jews, and continues until today."},{"v":16,"t":"But the eleven disciples went into Galilee, to the mountain where Jesus had sent them."},{"v":17,"t":"When they saw him, they bowed down to him; but some doubted."},{"v":18,"t":"Jesus came to them and spoke to them, saying, “All authority has been given to me in heaven and on earth."},{"v":19,"t":"Go and make disciples of all nations, baptizing them in the name of the Father and of the Son and of the Holy Spirit,"},{"v":20,"t":"teaching them to observe all things that I commanded you. Behold, I am with you always, even to the end of the age.” Amen."}],"hr":[{"v":1,"t":"Po suboti, u osvit prvoga dana u tjednu, dođe Marija Magdalena i druga Marija pogledati grob."},{"v":2,"t":"I gle, nastade žestok potres jer anđeo Gospodnji siđe s neba, pristupi, otkotrlja kamen i sjede na nj."},{"v":3,"t":"Lice mu bijaše kao munja, a odjeća bijela kao snijeg."},{"v":4,"t":"Od straha pred njim zadrhtaše stražari i obamriješe."},{"v":5,"t":"A anđeo progovori ženama: “Vi se ne bojte! Ta znam: Isusa Raspetoga tražite!"},{"v":6,"t":"Nije ovdje! Uskrsnu kako reče. Hajde, vidite mjesto gdje je ležao"},{"v":7,"t":"pa pođite žurno i javite njegovim učenicima da uskrsnu od mrtvih. I evo, ide pred vama u Galileju. Ondje ćete ga vidjeti. Evo, rekoh vam.”"},{"v":8,"t":"One otiđoše žurno s groba te sa strahom i velikom radošću otrčaše javiti njegovim učenicima."},{"v":9,"t":"Kad eto im Isusa u susret! Reče im: “Zdravo!” One polete k njemu, obujme mu noge i ničice mu se poklone."},{"v":10,"t":"Tada im Isus reče: “Ne bojte se! Idite, javite mojoj braći da pođu u Galileju! Ondje će me vidjeti!”"},{"v":11,"t":"Dok su one odlazile, gle, neki od straže dođoše u grad i javiše glavarima svećeničkim sve što se dogodilo."},{"v":12,"t":"Oni se sabraše sa starješinama na vijećanje, uzeše mnogo novaca i dadoše vojnicima"},{"v":13,"t":"govoreći: “Recite: 'Noću dok smo mi spavali, dođoše njegovi učenici i ukradoše ga.'"},{"v":14,"t":"Ako to dočuje upravitelj, mi ćemo ga uvjeriti i sve učiniti da vi budete bez brige.”"},{"v":15,"t":"Oni uzeše novac i učiniše kako bijahu poučeni. I razglasilo se to među Židovima - sve do danas."},{"v":16,"t":"Jedanaestorica pođoše u Galileju na goru kamo im je naredio Isus."},{"v":17,"t":"Kad ga ugledaše, padoše ničice preda nj. A neki posumnjaše."},{"v":18,"t":"Isus im pristupi i prozbori: “Dana mi je sva vlast na nebu i na zemlji!"},{"v":19,"t":"Pođite dakle i učinite mojim učenicima sve narode krsteći ih u ime Oca i Sina i Duha Svetoga"},{"v":20,"t":"i učeći ih čuvati sve što sam vam zapovjedio!” “I evo, ja sam s vama u sve dane - do svršetka svijeta.”"}]}},"MRK":{"1":{"fa":[{"v":1,"t":"ابتدا انجیل عیسی مسیح پسر خدا."},{"v":2,"t":"چنانکه در اشعیا نبی مکتوب است، «اینک رسول خود را پیش روی تو می‌فرستم تاراه تو را پیش تو مهیا سازد."},{"v":3,"t":"صدای ندا کننده‌ای در بیابان که راه خداوند را مهیا سازید و طرق او راراست نمایید.»"},{"v":4,"t":"یحیی تعمید‌دهنده در بیابان ظاهر شد وبجهت آمرزش گناهان به تعمید توبه موعظه می‌نمود."},{"v":5,"t":"و تمامی مرز و بوم یهودیه و جمیع سکنه اورشلیم نزد وی بیرون شدند و به گناهان خود معترف گردیده، در رود اردون از او تعمیدمی یافتند."},{"v":6,"t":"و یحیی را لباس از پشم شتر وکمربند چرمی بر کمر می‌بود و خوراک وی ازملخ و عسل بری."},{"v":7,"t":"و موعظه می‌کرد و می‌گفت که «بعد از من کسی تواناتر از من می‌آید که لایق آن نیستم که خم شده، دوال نعلین او را باز کنم."},{"v":8,"t":"من شما را به آب تعمید دادم. لیکن او شما را به روح‌القدس تعمید خواهد داد.»"},{"v":9,"t":"و واقع شد در آن ایام که عیسی از ناصره جلیل آمده در اردن از یحیی تعمید یافت."},{"v":10,"t":"وچون از آب برآمد، در ساعت آسمان را شکافته دید و روح را که مانند کبوتری بروی نازل می‌شود."},{"v":11,"t":"و آوازی از آسمان در‌رسید که «توپسر حبیب من هستی که از تو خشنودم.»"},{"v":12,"t":"پس بی‌درنگ روح وی را به بیابان می‌برد."},{"v":13,"t":"و مدت چهل روز در صحرا بود و شیطان او راتجربه می‌کرد و با وحوش بسر می‌برد و فرشتگان او را پرستاری می‌نمودند."},{"v":14,"t":"و بعد از گرفتاری یحیی، عیسی به جلیل آمده، به بشارت ملکوت خدا موعظه کرده،"},{"v":15,"t":"می گفت: «وقت تمام شد و ملکوت خدانزدیک است. پس توبه کنید و به انجیل ایمان بیاورید.»"},{"v":16,"t":"و چون به کناره دریای جلیل می‌گشت، شمعون و برادرش اندریاس را دید که دامی دردریا می‌اندازند زیرا که صیاد بودند."},{"v":17,"t":"عیسی ایشان را گفت: «از عقب من آیید که شما را صیادمردم گردانم.»"},{"v":18,"t":"بی‌تامل دامهای خود را گذارده، از پی او روانه شدند."},{"v":19,"t":"و از آنجا قدری پیشتررفته، یعقوب بن زبدی و برادرش یوحنا را دید که در کشتی دامهای خود را اصلاح می‌کنند."},{"v":20,"t":"درحال ایشان را دعوت نمود. پس پدر خود زبدی را با مزدوران در کشتی گذارده، از عقب وی روانه شدند."},{"v":21,"t":"و چون وارد کفرناحوم شدند، بی‌تامل درروز سبت به کنیسه درآمده، به تعلیم دادن شروع کرد،"},{"v":22,"t":"به قسمی که از تعلیم وی حیران شدند، زیرا که ایشان را مقتدرانه تعلیم می‌داد نه مانندکاتبان."},{"v":23,"t":"و در کنیسه ایشان شخصی بود که روح پلیدداشت. ناگاه صیحه زده،"},{"v":24,"t":"گفت: «ای عیسی ناصری ما را با تو چه‌کار است؟ آیا برای هلاک کردن ما آمدی؟ تو را می‌شناسم کیستی، ای قدوس خدا!»"},{"v":25,"t":"عیسی به وی نهیب داده، گفت: «خاموش شو و از او درآی!»"},{"v":26,"t":"در ساعت آن روح خبیث او را مصروع نمود و به آواز بلند صدازده، از او بیرون آمد."},{"v":27,"t":"و همه متعجب شدند، بحدی که از همدیگر سوال کرده، گفتند: «این چیست و این چه تعلیم تازه است که ارواح پلید رانیز با قدرت امر می‌کند و اطاعتش می‌نمایند؟»"},{"v":28,"t":"و اسم او فور در تمامی مرز و بوم جلیل شهرت یافت."},{"v":29,"t":"و از کنیسه بیرون آمده، فور با یعقوب ویوحنا به خانه شمعون و اندریاس درآمدند."},{"v":30,"t":"ومادر‌زن شمعون تب کرده، خوابیده بود. درساعت وی را از حالت او خبر دادند."},{"v":31,"t":"پس نزدیک شده، دست او را گرفته، برخیزانیدش که همان وقت تب از او زایل شد و به خدمت گذاری ایشان مشغول گشت."},{"v":32,"t":"شامگاه چون آفتاب به مغرب شد، جمیع مریضان و مجانین را پیش او آوردند."},{"v":33,"t":"و تمام شهر بر در خانه ازدحام نمودند."},{"v":34,"t":"و بسا کسانی را که به انواع امراض مبتلا بودند، شفا داد ودیوهای بسیاری بیرون کرده، نگذارد که دیوهاحرف زنند زیرا که او را شناختند."},{"v":35,"t":"بامدادان قبل از صبح برخاسته، بیرون رفت و به ویرانه‌ای رسیده، در آنجا به دعا مشغول شد."},{"v":36,"t":"و شمعون و رفقایش در‌پی او شتافتند."},{"v":37,"t":"چون او را دریافتند، گفتند: «همه تو رامی طلبند.»"},{"v":38,"t":"بدیشان گفت: «به دهات مجاورهم برویم تا در آنها نیز موعظه کنم، زیرا که بجهت این کار بیرون آمدم.»"},{"v":39,"t":"پس در تمام جلیل درکنایس ایشان وعظ می‌نمود و دیوها را اخراج می‌کرد."},{"v":40,"t":"و ابرصی پیش وی آمده، استدعا کرد وزانو زده، بدو گفت: «اگر بخواهی، می‌توانی مراطاهر سازی!»"},{"v":41,"t":"عیسی ترحم نموده، دست خودرا دراز کرد و او را لمس نموده، گفت: «می‌خواهم. طاهر شو!»"},{"v":42,"t":"و چون سخن گفت، فی الفور برص از او زایل شده، پاک گشت."},{"v":43,"t":"و اورا قدغن کرد و فور مرخص فرموده،"},{"v":44,"t":"گفت: «زنهار کسی را خبر مده، بلکه رفته خود را به کاهن بنما و آنچه موسی فرموده، بجهت تطهیر خودبگذران تا برای ایشان شهادتی بشود.»"},{"v":45,"t":"لیکن اوبیرون رفته، به موعظه نمودن و شهرت دادن این امر شروع کرد، بقسمی که بعد از آن او نتوانست آشکارا به شهر درآید بلکه در ویرانه های بیرون بسر می‌برد و مردم از همه اطراف نزد وی می‌آمدند."}],"en":[{"v":1,"t":"The beginning of the Good News of Jesus Christ, the Son of God."},{"v":2,"t":"As it is written in the prophets, “Behold, I send my messenger before your face, who will prepare your way before you:"},{"v":3,"t":"the voice of one crying in the wilderness, ‘Make ready the way of the Lord! Make his paths straight!’”"},{"v":4,"t":"John came baptizing in the wilderness and preaching the baptism of repentance for forgiveness of sins."},{"v":5,"t":"All the country of Judea and all those of Jerusalem went out to him. They were baptized by him in the Jordan river, confessing their sins."},{"v":6,"t":"John was clothed with camel’s hair and a leather belt around his waist. He ate locusts and wild honey."},{"v":7,"t":"He preached, saying, “After me comes he who is mightier than I, the strap of whose sandals I am not worthy to stoop down and loosen."},{"v":8,"t":"I baptized you in water, but he will baptize you in the Holy Spirit.”"},{"v":9,"t":"In those days, Jesus came from Nazareth of Galilee, and was baptized by John in the Jordan."},{"v":10,"t":"Immediately coming up from the water, he saw the heavens parting and the Spirit descending on him like a dove."},{"v":11,"t":"A voice came out of the sky, “You are my beloved Son, in whom I am well pleased.”"},{"v":12,"t":"Immediately the Spirit drove him out into the wilderness."},{"v":13,"t":"He was there in the wilderness forty days, tempted by Satan. He was with the wild animals; and the angels were serving him."},{"v":14,"t":"Now after John was taken into custody, Jesus came into Galilee, preaching the Good News of God’s Kingdom,"},{"v":15,"t":"and saying, “The time is fulfilled, and God’s Kingdom is at hand! Repent, and believe in the Good News.”"},{"v":16,"t":"Passing along by the sea of Galilee, he saw Simon and Andrew, the brother of Simon, casting a net into the sea, for they were fishermen."},{"v":17,"t":"Jesus said to them, “Come after me, and I will make you into fishers for men.”"},{"v":18,"t":"Immediately they left their nets, and followed him."},{"v":19,"t":"Going on a little further from there, he saw James the son of Zebedee, and John his brother, who were also in the boat mending the nets."},{"v":20,"t":"Immediately he called them, and they left their father, Zebedee, in the boat with the hired servants, and went after him."},{"v":21,"t":"They went into Capernaum, and immediately on the Sabbath day he entered into the synagogue and taught."},{"v":22,"t":"They were astonished at his teaching, for he taught them as having authority, and not as the scribes."},{"v":23,"t":"Immediately there was in their synagogue a man with an unclean spirit, and he cried out,"},{"v":24,"t":"saying, “Ha! What do we have to do with you, Jesus, you Nazarene? Have you come to destroy us? I know who you are: the Holy One of God!”"},{"v":25,"t":"Jesus rebuked him, saying, “Be quiet, and come out of him!”"},{"v":26,"t":"The unclean spirit, convulsing him and crying with a loud voice, came out of him."},{"v":27,"t":"They were all amazed, so that they questioned among themselves, saying, “What is this? A new teaching? For with authority he commands even the unclean spirits, and they obey him!”"},{"v":28,"t":"The report of him went out immediately everywhere into all the region of Galilee and its surrounding area."},{"v":29,"t":"Immediately, when they had come out of the synagogue, they came into the house of Simon and Andrew, with James and John."},{"v":30,"t":"Now Simon’s wife’s mother lay sick with a fever, and immediately they told him about her."},{"v":31,"t":"He came and took her by the hand and raised her up. The fever left her immediately, and she served them."},{"v":32,"t":"At evening, when the sun had set, they brought to him all who were sick and those who were possessed by demons."},{"v":33,"t":"All the city was gathered together at the door."},{"v":34,"t":"He healed many who were sick with various diseases and cast out many demons. He didn’t allow the demons to speak, because they knew him."},{"v":35,"t":"Early in the morning, while it was still dark, he rose up and went out, and departed into a deserted place, and prayed there."},{"v":36,"t":"Simon and those who were with him searched for him."},{"v":37,"t":"They found him and told him, “Everyone is looking for you.”"},{"v":38,"t":"He said to them, “Let’s go elsewhere into the next towns, that I may preach there also, because I came out for this reason.”"},{"v":39,"t":"He went into their synagogues throughout all Galilee, preaching and casting out demons."},{"v":40,"t":"A leper came to him, begging him, kneeling down to him, and saying to him, “If you want to, you can make me clean.”"},{"v":41,"t":"Being moved with compassion, he stretched out his hand, and touched him, and said to him, “I want to. Be made clean.”"},{"v":42,"t":"When he had said this, immediately the leprosy departed from him and he was made clean."},{"v":43,"t":"He strictly warned him and immediately sent him out,"},{"v":44,"t":"and said to him, “See that you say nothing to anybody, but go show yourself to the priest and offer for your cleansing the things which Moses commanded, for a testimony to them.”"},{"v":45,"t":"But he went out, and began to proclaim it much, and to spread about the matter, so that Jesus could no more openly enter into a city, but was outside in desert places. People came to him from everywhere."}],"hr":[{"v":1,"t":"Početak Evanđelja Isusa Krista Sina Božjega."},{"v":2,"t":"Pisano je u Izaiji proroku: Evo šaljem glasnika svoga pred licem tvojim da ti pripravi put."},{"v":3,"t":"Glas viče u pustinji: Pripravite put Gospodinu, poravnite mu staze!"},{"v":4,"t":"Tako se pojavi Ivan: krstio je u pustinji i propovijedao krst obraćenja na otpuštenje grijeha."},{"v":5,"t":"Grnula k njemu sva judejska zemlja i svi Jeruzalemci: primali su od njega krštenje u rijeci Jordanu ispovijedajući svoje grijehe."},{"v":6,"t":"Ivan bijaše odjeven u devinu dlaku, s kožnatim pojasom oko bokova; hranio se skakavcima i divljim medom."},{"v":7,"t":"I propovijedao je: “Nakon mene dolazi jači od mene. Ja nisam dostojan sagnuti se i odriješiti mu remenje na obući."},{"v":8,"t":"Ja vas krstim vodom, a on će vas krstiti Duhom Svetim.”"},{"v":9,"t":"Onih dana dođe Isus iz Nazareta galilejskoga i primi u Jordanu krštenje od Ivana."},{"v":10,"t":"I odmah, čim izađe iz vode, ugleda otvorena nebesa i Duha poput goluba gdje silazi na nj,"},{"v":11,"t":"a glas se zaori s nebesa: Ti si Sin moj, Ljubljeni! U tebi mi sva milina!"},{"v":12,"t":"I odmah ga Duh nagna u pustinju."},{"v":13,"t":"I bijaše u pustinji četrdeset dana, gdje ga je iskušavao Sotona; bijaše sa zvijerima, a anđeli mu služahu."},{"v":14,"t":"A pošto Ivan bijaše predan, otiđe Isus u Galileju. Propovijedao je evanđelje Božje:"},{"v":15,"t":"“Ispunilo se vrijeme, približilo se kraljevstvo Božje! Obratite se i vjerujte evanđelju!”"},{"v":16,"t":"I prolazeći uz Galilejsko more, ugleda Šimuna i Andriju, brata Šimunova, gdje ribare na moru; bijahu ribari."},{"v":17,"t":"I reče im Isus: “Hajdete za mnom i učinit ću vas ribarima ljudi!”"},{"v":18,"t":"Oni odmah ostaviše mreže i pođoše za njim."},{"v":19,"t":"Pošavši malo naprijed, ugleda Jakova Zebedejeva i njegova brata Ivana: u lađi su krpali mreže."},{"v":20,"t":"Odmah pozva i njih. Oni ostave oca Zebedeja u lađi s nadničarima i otiđu za njim."},{"v":21,"t":"I stignu u Kafarnaum. Odmah u subotu uđe on u sinagogu i poče naučavati."},{"v":22,"t":"Bijahu zaneseni njegovim naukom. Ta učio ih je kao onaj koji ima vlast, a ne kao pismoznanci."},{"v":23,"t":"A u njihovoj se sinagogi upravo zatekao čovjek opsjednut nečistim duhom. On povika:"},{"v":24,"t":"“Što ti imaš s nama, Isuse Nazarećanine? Došao si da nas uništiš? Znam tko si: Svetac Božji!”"},{"v":25,"t":"Isus mu zaprijeti: “Umukni i iziđi iz njega!”"},{"v":26,"t":"Nato nečisti duh potrese njime pa povika iz svega glasa i iziđe iz njega."},{"v":27,"t":"Svi se zaprepastiše te se zapitkivahu: “Što li je ovo? Nova li i snažna nauka! Pa i samim nečistim dusima zapovijeda, i pokoravaju mu se.”"},{"v":28,"t":"I pročulo se odmah o njemu posvuda, po svoj okolici galilejskoj."},{"v":29,"t":"I odmah pošto iziđoše iz sinagoge, uđe s Jakovom i Ivanom u kuću Šimunovu i Andrijinu."},{"v":30,"t":"A punica Šimunova ležala u ognjici. I odmah mu kažu za nju."},{"v":31,"t":"On pristupi, prihvati je za ruku i podiže. I pusti je ognjica. I posluživaše im."},{"v":32,"t":"Uvečer, kad sunce zađe, donošahu preda nj sve bolesne i opsjednute."},{"v":33,"t":"I sav je grad nagrnuo k vratima."},{"v":34,"t":"I on ozdravi bolesnike - a bijahu mnogi i razne im bolesti - i zloduhe mnoge izagna. I ne dopusti zlodusima govoriti jer su ga znali."},{"v":35,"t":"Rano ujutro, još za mraka, ustane, iziđe i povuče se na samotno mjesto i ondje se moljaše."},{"v":36,"t":"Potražiše ga Šimun i njegovi drugovi."},{"v":37,"t":"Kad ga nađoše, rekoše mu: “Svi te traže.”"},{"v":38,"t":"Kaže im: “Hajdemo drugamo, u obližnja mjesta, da i ondje propovijedam! Ta zato sam došao.”"},{"v":39,"t":"I prođe svom Galilejom: propovijedao je u njihovim sinagogama i zloduhe izgonio."},{"v":40,"t":"I dođe k njemu neki gubavac, klekne i zamoli: “Ako hoćeš, možeš me očistiti!”"},{"v":41,"t":"Isus ganut pruži ruku, dotače ga se pa će mu: “Hoću, budi čist!”"},{"v":42,"t":"I odmah nesta s njega gube i očisti se."},{"v":43,"t":"Isus se otrese na nj i odmah ga otpravi"},{"v":44,"t":"riječima: “Pazi, nikomu ništa ne kazuj, nego idi, pokaži se svećeniku i prinesi za svoje očišćenje što propisa Mojsije, njima za svjedočanstvo.”"},{"v":45,"t":"Ali čim iziđe, stane on uvelike pripovijedati i razglašavati događaj tako da Isus više nije mogao javno ući u grad, nego se zadržavao vani na samotnim mjestima. I dolažahu k njemu odasvud."}]},"2":{"fa":[{"v":1,"t":"و بعد از چندی، باز وارد کفرناحوم شده، چون شهرت یافت که در خانه است،"},{"v":2,"t":"بی درنگ جمعی ازدحام نمودند بقسمی که بیرون در نیز گنجایش نداشت و برای ایشان کلام را بیان می‌کرد."},{"v":3,"t":"که ناگاه بعضی نزد وی آمده مفلوجی را به‌دست چهار نفر برداشته، آوردند."},{"v":4,"t":"و چون به‌سبب جمعیت نتوانستند نزد او برسند، طاق جایی را که او بود باز کرده و شکافته، تختی را که مفلوج بر آن خوابیده بود، به زیر هشتند."},{"v":5,"t":"عیسی چون ایمان ایشان را دید، مفلوج را گفت: «ای فرزند، گناهان تو آمرزیده شد.»"},{"v":6,"t":"لیکن بعضی از کاتبان که در آنجا نشسته بودند، در دل خود تفکر نمودند"},{"v":7,"t":"که «چرا این شخص چنین کفر می‌گوید؟ غیر از خدای واحد، کیست که بتواند گناهان را بیامرزد؟»"},{"v":8,"t":"در ساعت عیسی در روح خود ادراک نموده که با خود چنین فکر می‌کنند، بدیشان گفت: «از بهر‌چه این خیالات را به‌خاطر خود راه می‌دهید؟"},{"v":9,"t":"کدام سهل تر است؟ مفلوج را گفتن گناهان تو آمرزیده شد؟ یا گفتن برخیز و بستر خود را برداشته بخرام؟"},{"v":10,"t":"لیکن تا بدانید که پسر انسان رااستطاعت آمرزیدن گناهان بر روی زمین هست...» مفلوج را گفت:"},{"v":11,"t":"«تو را می‌گویم برخیز و بستر خود را برداشته، به خانه خود برو!»"},{"v":12,"t":"او برخاست و بی‌تامل بستر خود را برداشته، پیش روی همه روانه شد بطوری که همه حیران شده، خدا را تمجید نموده، گفتند: «مثل این امرهرگز ندیده بودیم!»"},{"v":13,"t":"و باز به کناره دریا رفت و تمام آن گروه نزداو آمدند و ایشان را تعلیم می‌داد."},{"v":14,"t":"و هنگامی که می‌رفت لاوی ابن حلفی را بر باجگاه نشسته دید. بدو گفت: «از عقب من بیا!» پس برخاسته، درعقب وی شتافت."},{"v":15,"t":"و وقتی که او در خانه وی نشسته بود، بسیاری از باجگیران و گناهکاران باعیسی و شاگردانش نشستند زیرا بسیار بودند وپیروی او می‌کردند."},{"v":16,"t":"و چون کاتبان و فریسیان او را دیدند که با باجگیران و گناهکاران می‌خورد، به شاگردان او گفتند: «چرا با باجگیران وگناهکاران اکل و شرب می‌نماید؟»"},{"v":17,"t":"عیسی چون این را شنید، بدیشان گفت: «تندرستان احتیاج به طبیب ندارند بلکه مریضان. و من نیامدم تا عادلان را بلکه تا گناهکاران را به توبه دعوت کنم.»"},{"v":18,"t":"و شاگردان یحیی و فریسیان روزه می‌داشتند. پس آمده، بدو گفتند: «چون است که شاگردان یحیی و فریسیان روزه می‌دارند وشاگردان تو روزه نمی دارند؟»"},{"v":19,"t":"عیسی بدیشان گفت: «آیا ممکن است پسران خانه عروسی مادامی که داماد با ایشان است روزه بدارند؟ زمانی که داماد را با خود دارند، نمی توانند روزه‌دارند."},{"v":20,"t":"لیکن ایامی می‌آید که داماد از ایشان گرفته شود. در آن ایام روزه خواهند داشت."},{"v":21,"t":"وهیچ‌کس بر جامه کهنه، پاره‌ای از پارچه نو وصله نمی کند، والا آن وصله نو از آن کهنه جدامی گردد و دریدگی بدتر می‌شود."},{"v":22,"t":"و کسی شراب نو را در مشکهای کهنه نمی ریزد وگرنه آن شراب نو مشکها را بدرد و شراب ریخته، مشکهاتلف می‌گردد. بلکه شراب نو را در مشکهای نوباید ریخت.»"},{"v":23,"t":"و چنان افتاد که روز سبتی از میان مزرعه‌ها می‌گذشت و شاگردانش هنگامی که می‌رفتند، به چیدن خوشه‌ها شروع کردند."},{"v":24,"t":"فریسیان بدو گفتند: «اینک چرا در روزسبت مرتکب عملی می‌باشند که روا نیست؟»"},{"v":25,"t":"او بدیشان گفت: «مگر هرگز نخوانده ایدکه داود چه کرد چون او و رفقایش محتاج وگرسنه بودند؟"},{"v":26,"t":"چگونه در ایام ابیتار رئیس کهنه به خانه خدا درآمده، نان تقدمه راخورد که خوردن آن جز به کاهنان روا نیست و به رفقای خود نیز داد؟»"},{"v":27,"t":"و بدیشان گفت: «سبت بجهت انسان مقرر شد نه انسان برای سبت."},{"v":28,"t":"بنابراین پسر انسان مالک سبت نیزهست.»"}],"en":[{"v":1,"t":"When he entered again into Capernaum after some days, it was heard that he was at home."},{"v":2,"t":"Immediately many were gathered together, so that there was no more room, not even around the door; and he spoke the word to them."},{"v":3,"t":"Four people came, carrying a paralytic to him."},{"v":4,"t":"When they could not come near to him for the crowd, they removed the roof where he was. When they had broken it up, they let down the mat that the paralytic was lying on."},{"v":5,"t":"Jesus, seeing their faith, said to the paralytic, “Son, your sins are forgiven you.”"},{"v":6,"t":"But there were some of the scribes sitting there and reasoning in their hearts,"},{"v":7,"t":"“Why does this man speak blasphemies like that? Who can forgive sins but God alone?”"},{"v":8,"t":"Immediately Jesus, perceiving in his spirit that they so reasoned within themselves, said to them, “Why do you reason these things in your hearts?"},{"v":9,"t":"Which is easier, to tell the paralytic, ‘Your sins are forgiven;’ or to say, ‘Arise, and take up your bed, and walk’?"},{"v":10,"t":"But that you may know that the Son of Man has authority on earth to forgive sins”—he said to the paralytic—"},{"v":11,"t":"“I tell you, arise, take up your mat, and go to your house.”"},{"v":12,"t":"He arose, and immediately took up the mat and went out in front of them all, so that they were all amazed and glorified God, saying, “We never saw anything like this!”"},{"v":13,"t":"He went out again by the seaside. All the multitude came to him, and he taught them."},{"v":14,"t":"As he passed by, he saw Levi the son of Alphaeus sitting at the tax office. He said to him, “Follow me.” And he arose and followed him."},{"v":15,"t":"He was reclining at the table in his house, and many tax collectors and sinners sat down with Jesus and his disciples, for there were many, and they followed him."},{"v":16,"t":"The scribes and the Pharisees, when they saw that he was eating with the sinners and tax collectors, said to his disciples, “Why is it that he eats and drinks with tax collectors and sinners?”"},{"v":17,"t":"When Jesus heard it, he said to them, “Those who are healthy have no need for a physician, but those who are sick. I came not to call the righteous, but sinners to repentance.”"},{"v":18,"t":"John’s disciples and the Pharisees were fasting, and they came and asked him, “Why do John’s disciples and the disciples of the Pharisees fast, but your disciples don’t fast?”"},{"v":19,"t":"Jesus said to them, “Can the groomsmen fast while the bridegroom is with them? As long as they have the bridegroom with them, they can’t fast."},{"v":20,"t":"But the days will come when the bridegroom will be taken away from them, and then they will fast in that day."},{"v":21,"t":"No one sews a piece of unshrunk cloth on an old garment, or else the patch shrinks and the new tears away from the old, and a worse hole is made."},{"v":22,"t":"No one puts new wine into old wineskins; or else the new wine will burst the skins, and the wine pours out, and the skins will be destroyed; but they put new wine into fresh wineskins.”"},{"v":23,"t":"He was going on the Sabbath day through the grain fields; and his disciples began, as they went, to pluck the ears of grain."},{"v":24,"t":"The Pharisees said to him, “Behold, why do they do that which is not lawful on the Sabbath day?”"},{"v":25,"t":"He said to them, “Did you never read what David did when he had need and was hungry—he, and those who were with him?"},{"v":26,"t":"How he entered into God’s house at the time of Abiathar the high priest, and ate the show bread, which is not lawful to eat except for the priests, and gave also to those who were with him?”"},{"v":27,"t":"He said to them, “The Sabbath was made for man, not man for the Sabbath."},{"v":28,"t":"Therefore the Son of Man is lord even of the Sabbath.”"}],"hr":[{"v":1,"t":"I pošto nakon nekoliko dana opet uđe u Kafarnaum, pročulo se da je u kući."},{"v":2,"t":"I skupiše se mnogi te više nije bilo mjesta ni pred vratima. On im navješćivaše Riječ."},{"v":3,"t":"I dođu noseći k njemu uzetoga. Nosila ga četvorica."},{"v":4,"t":"Budući da ga zbog mnoštva nisu mogli unijeti k njemu, otkriju krov nad mjestom gdje bijaše Isus. Načinivši otvor, spuste postelju na kojoj je uzeti ležao."},{"v":5,"t":"Vidjevši njihovu vjeru, kaže Isus uzetome: “Sinko! Otpuštaju ti se grijesi.”"},{"v":6,"t":"Sjedjeli su ondje neki pismoznanci koji počeše mudrovati u sebi:"},{"v":7,"t":"“Što to ovaj govori? Huli! Ta tko može grijehe otpuštati doli Bog jedini?”"},{"v":8,"t":"Isus duhom odmah proniknu da tako mudruju u sebi, pa će im: “Što to mudrujete u sebi?"},{"v":9,"t":"Ta što je lakše? Reći uzetomu: 'Otpuštaju ti se grijesi' ili reći: 'Ustani, uzmi svoju postelju i hodi?'"},{"v":10,"t":"Ali da znate: vlastan je Sin Čovječji na zemlji otpuštati grijehe!” I reče uzetomu:"},{"v":11,"t":"“Tebi zapovijedam, ustani, uzmi postelju i pođi kući!”"},{"v":12,"t":"I on usta, uze odmah postelju i iziđe na očigled svima. Svi su zaneseni slavili Boga govoreći: “Takvo što nikad još ne vidjesmo!”"},{"v":13,"t":"Isus ponovno iziđe k moru. Sve je ono mnoštvo grnulo k njemu i on ih poučavaše."},{"v":14,"t":"Prolazeći ugleda Levija Alfejeva gdje sjedi u carinarnici. I kaže mu: “Pođi za mnom!” On usta i pođe za njim."},{"v":15,"t":"Kada zatim Isus bijaše za stolom u njegovoj kući, nađoše se za stolom s njime i njegovim učenicima i mnogi carinici i grešnici. Bilo ih je uistinu mnogo. A slijedili su ga"},{"v":16,"t":"i pismoznanci farizejske sljedbe pa vidjevši da jede s grešnicima i carinicima rekoše njegovim učenicima: “Zašto jede s carinicima i grešnicima?”"},{"v":17,"t":"Čuvši to, Isus im reče: “Ne treba zdravima liječnika, nego bolesnima! Ne dođoh zvati pravednike, nego grešnike.”"},{"v":18,"t":"Ivanovi su učenici i farizeji postili. I dođu neki i kažu mu: “Zašto učenici Ivanovi i učenici farizejski poste, a tvoji učenici ne poste?”"},{"v":19,"t":"Nato im Isus reče: “Mogu li svatovi postiti dok je zaručnik s njima? Dokle god imaju zaručnika sa sobom, ne mogu postiti."},{"v":20,"t":"Doći će već dani kad će im se ugrabiti zaručnik i tada će postiti u onaj dan!”"},{"v":21,"t":"“Nitko ne prišiva krpe od sirova sukna na staro odijelo. Inače nova zakrpa vuče sa starog odijela pa nastane još veća rupa.”"},{"v":22,"t":"“I nitko ne ulijeva novo vino u stare mješine. Inače će vino poderati mješine pa propade i vino i mješine. Nego - novo vino u nove mješine!”"},{"v":23,"t":"Jedne je subote prolazio kroz usjeve. Njegovi učenici počeše putem trgati klasje. A farizeji mu rekoše:"},{"v":24,"t":"“Gle! Zašto čine što subotom nije dopušteno?”"},{"v":25,"t":"Isus im odgovori: “Zar nikad niste čitali što učini David kad ogladnje te se nađe u potrebi on i njegovi pratioci?"},{"v":26,"t":"Kako za velikog svećenika Ebjatara uđe u Dom Božji i pojede prinesene kruhove kojih ne smije jesti nitko osim svećenika; a on dade i svojim pratiocima?”"},{"v":27,"t":"I govoraše im: “Subota je stvorena radi čovjeka, a ne čovjek radi subote."},{"v":28,"t":"Tako, Sin Čovječji gospodar je subote!”"}]},"3":{"fa":[{"v":1,"t":"و باز به کنیسه درآمده، در آنجا مرد دست خشکی بود."},{"v":2,"t":"و مراقب وی بودند که شاید او را در سبت شفا دهد تا مدعی او گردند."},{"v":3,"t":"پس بدان مرد دست خشک گفت: «در میان بایست!»"},{"v":4,"t":"و بدیشان گفت: «آیا در روز سبت کدام جایز است؟ نیکویی‌کردن یا بدی؟ جان رانجات دادن یا هلاک کردن؟» ایشان خاموش ماندند."},{"v":5,"t":"پس چشمان خود را بر ایشان باغضب گردانیده، زیرا که از سنگدلی ایشان محزون بود، به آن مرد گفت: «دست خود رادراز کن!» پس دراز کرده، دستش صحیح گشت."},{"v":6,"t":"در ساعت فریسیان بیرون رفته، با هیرودیان درباره او شورا نمودند که چطور او را هلاک کنند."},{"v":7,"t":"و عیسی با شاگردانش به سوی دریا آمد وگروهی بسیار از جلیل به عقب او روانه شدند،"},{"v":8,"t":"واز یهودیه و از اورشلیم و ادومیه و آن طرف اردن و از حوالی صور و صیدون نیز جمعی کثیر، چون اعمال او را شنیدند، نزد وی آمدند."},{"v":9,"t":"و به شاگردان خود فرمود تا زورقی به‌سبب جمعیت، بجهت او نگاه دارند تا بر وی ازدحام ننمایند،"},{"v":10,"t":"زیرا که بسیاری را صحت می‌داد، بقسمی که هر‌که صاحب دردی بود بر او هجوم می‌آورد تااو را لمس نماید."},{"v":11,"t":"و ارواح پلید چون او رادیدند، پیش او به روی در‌افتادند و فریادکنان می‌گفتند که «تو پسر خدا هستی.»"},{"v":12,"t":"و ایشان را به تاکید بسیار فرمود که او را شهرت ندهند."},{"v":13,"t":"پس بر فراز کوهی برآمده، هر‌که راخواست به نزد خود طلبید و ایشان نزد او آمدند."},{"v":14,"t":"و دوازده نفر را مقرر فرمود تا همراه او باشند وتا ایشان را بجهت وعظ نمودن بفرستد،"},{"v":15,"t":"وایشان را قدرت باشد که مریضان را شفا دهند ودیوها را بیرون کنند."},{"v":16,"t":"و شمعون را پطرس نام نهاد."},{"v":17,"t":"و یعقوب پسر زبدی و یوحنا برادریعقوب؛ این هر دو را بوانرجس یعنی پسران رعد نام گذارد."},{"v":18,"t":"و اندریاس و فیلپس و برتولما و متی و توما و یعقوب بن حلفی و تدی وشمعون قانوی،"},{"v":19,"t":"و یهودای اسخریوطی که او راتسلیم کرد."},{"v":20,"t":"و چون به خانه درآمدند، باز جمعی فراهم آمدند بطوری که ایشان فرصت نان خوردن هم نکردند."},{"v":21,"t":"و خویشان او چون شنیدند، بیرون آمدند تا او را بردارند زیرا گفتند بی‌خود شده است."},{"v":22,"t":"و کاتبانی که از اورشلیم آمده بودند، گفتند که بعلزبول دارد و به یاری رئیس دیوها، دیوها را اخراج می‌کند."},{"v":23,"t":"پس ایشان را پیش طلبیده، مثلها زده، بدیشان گفت: «چطور می‌تواندشیطان، شیطان را بیرون کند؟"},{"v":24,"t":"و اگر مملکتی برخلاف خود منقسم شود، آن مملکت نتواندپایدار بماند."},{"v":25,"t":"و هرگاه خانه‌ای به ضد خویش منقسم شد، آن خانه نمی تواند استقامت داشته باشد."},{"v":26,"t":"و اگر شیطان با نفس خود مقاومت نمایدو منقسم شود، او نمی تواند قائم ماند بلکه هلاک می‌گردد."},{"v":27,"t":"و هیچ‌کس نمی تواند به خانه مردزورآور درآمده، اسباب او را غارت نماید، جزآنکه اول آن زورآور را ببندد و بعد از آن خانه اورا تاراج می‌کند."},{"v":28,"t":"هرآینه به شما می‌گویم که همه گناهان از بنی آدم آمرزیده می‌شود و هر قسم کفر که گفته باشند،"},{"v":29,"t":"لیکن هر‌که به روح‌القدس کفر گوید، تا به ابد آمرزیده نشود بلکه مستحق عذاب جاودانی بود.»"},{"v":30,"t":"زیرا که می‌گفتند روحی پلید دارد."},{"v":31,"t":"پس برادران و مادر او آمدند و بیرون ایستاده، فرستادند تا او را طلب کنند."},{"v":32,"t":"آنگاه جماعت گرد او نشسته بودند و به وی گفتند: «اینک مادرت و برادرانت بیرون تو را می‌طلبند.»"},{"v":33,"t":"در جواب ایشان گفت: «کیست مادر من وبرادرانم کیانند؟»"},{"v":34,"t":"پس بر آنانی که گرد وی نشسته بودند، نظر افکنده، گفت: «اینانند مادر وبرادرانم،"},{"v":35,"t":"زیرا هر‌که اراده خدا را به‌جا آردهمان برادر و خواهر و مادر من باشد.»"}],"en":[{"v":1,"t":"He entered again into the synagogue, and there was a man there whose hand was withered."},{"v":2,"t":"They watched him, whether he would heal him on the Sabbath day, that they might accuse him."},{"v":3,"t":"He said to the man whose hand was withered, “Stand up.”"},{"v":4,"t":"He said to them, “Is it lawful on the Sabbath day to do good or to do harm? To save a life or to kill?” But they were silent."},{"v":5,"t":"When he had looked around at them with anger, being grieved at the hardening of their hearts, he said to the man, “Stretch out your hand.” He stretched it out, and his hand was restored as healthy as the other."},{"v":6,"t":"The Pharisees went out, and immediately conspired with the Herodians against him, how they might destroy him."},{"v":7,"t":"Jesus withdrew to the sea with his disciples; and a great multitude followed him from Galilee, from Judea,"},{"v":8,"t":"from Jerusalem, from Idumaea, beyond the Jordan, and those from around Tyre and Sidon. A great multitude, hearing what great things he did, came to him."},{"v":9,"t":"He spoke to his disciples that a little boat should stay near him because of the crowd, so that they wouldn’t press on him."},{"v":10,"t":"For he had healed many, so that as many as had diseases pressed on him that they might touch him."},{"v":11,"t":"The unclean spirits, whenever they saw him, fell down before him and cried, “You are the Son of God!”"},{"v":12,"t":"He sternly warned them that they should not make him known."},{"v":13,"t":"He went up into the mountain and called to himself those whom he wanted, and they went to him."},{"v":14,"t":"He appointed twelve, that they might be with him, and that he might send them out to preach"},{"v":15,"t":"and to have authority to heal sicknesses and to cast out demons:"},{"v":16,"t":"Simon (to whom he gave the name Peter);"},{"v":17,"t":"James the son of Zebedee; and John, the brother of James, (whom he called Boanerges, which means, Sons of Thunder);"},{"v":18,"t":"Andrew; Philip; Bartholomew; Matthew; Thomas; James, the son of Alphaeus; Thaddaeus; Simon the Zealot;"},{"v":19,"t":"and Judas Iscariot, who also betrayed him. Then he came into a house."},{"v":20,"t":"The multitude came together again, so that they could not so much as eat bread."},{"v":21,"t":"When his friends heard it, they went out to seize him; for they said, “He is insane.”"},{"v":22,"t":"The scribes who came down from Jerusalem said, “He has Beelzebul,” and, “By the prince of the demons he casts out the demons.”"},{"v":23,"t":"He summoned them and said to them in parables, “How can Satan cast out Satan?"},{"v":24,"t":"If a kingdom is divided against itself, that kingdom cannot stand."},{"v":25,"t":"If a house is divided against itself, that house cannot stand."},{"v":26,"t":"If Satan has risen up against himself, and is divided, he can’t stand, but has an end."},{"v":27,"t":"But no one can enter into the house of the strong man to plunder unless he first binds the strong man; then he will plunder his house."},{"v":28,"t":"“Most certainly I tell you, all sins of the descendants of man will be forgiven, including their blasphemies with which they may blaspheme;"},{"v":29,"t":"but whoever may blaspheme against the Holy Spirit never has forgiveness, but is subject to eternal condemnation.”"},{"v":30,"t":"—because they said, “He has an unclean spirit.”"},{"v":31,"t":"His mother and his brothers came, and standing outside, they sent to him, calling him."},{"v":32,"t":"A multitude was sitting around him, and they told him, “Behold, your mother, your brothers, and your sisters are outside looking for you.”"},{"v":33,"t":"He answered them, “Who are my mother and my brothers?”"},{"v":34,"t":"Looking around at those who sat around him, he said, “Behold, my mother and my brothers!"},{"v":35,"t":"For whoever does the will of God is my brother, my sister, and mother.”"}],"hr":[{"v":1,"t":"Uđe ponovno u sinagogu. Bio je ondje čovjek usahle ruke."},{"v":2,"t":"A oni vrebahu hoće li ga Isus u subotu izliječiti, da ga optuže."},{"v":3,"t":"On kaže čovjeku usahle ruke: “Stani na sredinu!”"},{"v":4,"t":"A njima će: “Je li subotom dopušteno činiti dobro ili činiti zlo, život spasiti ili pogubiti?” No oni su šutjeli."},{"v":5,"t":"A on, ražalošćen okorjelošću srca njihova, srdito ih ošinu pogledom pa reče tom čovjeku: “Ispruži ruku!” On ispruži - i ruka mu zdrava!"},{"v":6,"t":"Farizeji iziđu i dadnu se odmah s herodovcima na vijećanje protiv njega kako da ga pogube."},{"v":7,"t":"Isus se s učenicima povuče k moru. Za njim je išao silan svijet iz Galileje. I iz Judeje,"},{"v":8,"t":"iz Jeruzalema, iz Idumeje, iz Transjordanije i iz okolice Tira i Sidona - silno je mnoštvo čulo što čini i nagrnulo k njemu."},{"v":9,"t":"Stoga reče učenicima neka mu se zbog mnoštva pripravi lađica da ga ne bi zgnjeli."},{"v":10,"t":"Jer mnoge je ozdravio pa su se svi koji bijahu pogođeni kakvim zlom bacali na nj da bi ga se dotakli."},{"v":11,"t":"A nečisti duhovi, čim bi ga spazili, padali bi preda nj i vikali: “Ti si Sin Božji!”"},{"v":12,"t":"A on im se oštro prijetio da ga ne prokazuju."},{"v":13,"t":"Uziđe na goru i pozove koje sam htjede. I dođoše k njemu."},{"v":14,"t":"I ustanovi dvanaestoricu da budu s njime i da ih šalje propovijedati"},{"v":15,"t":"s vlašću da izgone đavle."},{"v":16,"t":"Ustanovi dakle dvanaestoricu: Šimuna, kojemu nadjenu ime Petar,"},{"v":17,"t":"i Jakova Zebedejeva i Ivana, brata Jakovljeva, kojima nadjenu ime Boanerges, to jest Sinovi groma,"},{"v":18,"t":"i Andriju i Filipa i Bartolomeja i Mateja i Tomu i Jakova Alfejeva i Tadeja i Šimuna Kananajca"},{"v":19,"t":"i Judu Iškariotskoga, koji ga izda."},{"v":20,"t":"I dođe Isus u kuću. Opet se skupi toliko mnoštvo da nisu mogli ni jesti."},{"v":21,"t":"Čuvši to, dođoše njegovi da ga obuzdaju jer se govorilo: “Izvan sebe je!”"},{"v":22,"t":"I pismoznanci što siđoše iz Jeruzalema govorahu: “Beelzebula ima, po poglavici đavolskom izgoni đavle.”"},{"v":23,"t":"A on ih dozva pa im u prispodobama govoraše: “Kako može Sotona Sotonu izgoniti?"},{"v":24,"t":"Ako se kraljevstvo u sebi razdijeli, ono ne može opstati."},{"v":25,"t":"Ili: ako se kuća u sebi razdijeli, ona ne može opstati."},{"v":26,"t":"Ako je dakle Sotona sam na sebe ustao i razdijelio se, ne može opstati, nego mu je kraj."},{"v":27,"t":"Nitko, dakako, ne može u kuću jakoga ući i oplijeniti mu pokućstvo ako prije jakoga ne sveže. Tada će mu kuću oplijeniti!”"},{"v":28,"t":"Doista, kažem vam, sve će se oprostiti sinovima ljudskima, koliki god bili grijesi i hule kojima pohule."},{"v":29,"t":"No pohuli li tko na Duha Svetoga, nema oproštenja dovijeka; krivac je grijeha vječnoga.”"},{"v":30,"t":"Jer govorahu: “Duha nečistoga ima.”"},{"v":31,"t":"I dođu majka njegova i braća njegova. Ostanu vani, a k njemu pošalju neka ga pozovu."},{"v":32,"t":"Oko njega je sjedjelo mnoštvo. I reknu mu: “Eno vani majke tvoje i braće tvoje, traže te!”"},{"v":33,"t":"On im odgovori: “Tko je majka moja i braća moja?”"},{"v":34,"t":"I okruži pogledom po onima što su sjedjeli oko njega u krugu i kaže: “Evo majke moje, evo braće moje!"},{"v":35,"t":"Tko god vrši volju Božju, on mi je brat i sestra i majka.”"}]},"4":{"fa":[{"v":1,"t":"و باز به کناره دریا به تعلیم دادن شروع کردو جمعی کثیر نزد او جمع شدند بطوری که به کشتی سوار شده، بر دریا قرار گرفت و تمامی آن جماعت بر ساحل دریا حاضر بودند."},{"v":2,"t":"پس ایشان را به مثلها چیزهای بسیار می‌آموخت و درتعلیم خود بدیشان گفت:"},{"v":3,"t":"«گوش گیرید! اینک برزگری بجهت تخم پاشی بیرون رفت."},{"v":4,"t":"و چون تخم می‌پاشید، قدری بر راه ریخته شده، مرغان هوا آمده آنها را برچیدند."},{"v":5,"t":"و پاره‌ای بر سنگلاخ پاشیده شد، در جایی که خاک بسیار نبود. پس چون که زمین عمق نداشت به زودی رویید،"},{"v":6,"t":"وچون آفتاب برآمد، سوخته شد و از آنرو که ریشه نداشت خشکید."},{"v":7,"t":"و قدری در میان خارها ریخته شد و خارها نمو کرده، آن را خفه نمود که ثمری نیاورد."},{"v":8,"t":"و مابقی در زمین نیکو افتاد و حاصل پیدا نمود که رویید و نمو کرد و بارآورد، بعضی سی وبعضی شصت و بعضی صد.»"},{"v":9,"t":"پس گفت: «هر‌که گوش شنوا دارد، بشنود!»"},{"v":10,"t":"و چون به خلوت شد، رفقای او با آن دوازده شرح این مثل را از او پرسیدند."},{"v":11,"t":"به ایشان گفت: «به شما دانستن سر ملکوت خدا عطاشده، اما به آنانی که بیرونند، همه‌چیز به مثلهامی شود،"},{"v":12,"t":"تا نگران شده بنگرند و نبینند و شنواشده بشنوند و نفهمند، مبادا بازگشت کرده گناهان ایشان آمرزیده شود.»"},{"v":13,"t":"و بدیشان گفت: «آیا این مثل رانفهمیده‌اید؟ پس چگونه سایر مثلها را خواهیدفهمید؟"},{"v":14,"t":"برزگر کلام را می‌کارد."},{"v":15,"t":"و اینانند به کناره راه، جایی که کلام کاشته می‌شود؛ و چون شنیدند فور شیطان آمده کلام کاشته شده درقلوب ایشان را می‌رباید."},{"v":16,"t":"و ایض کاشته شده درسنگلاخ، کسانی می‌باشند که چون کلام رابشنوند، در حال آن را به خوشی قبول کنند،"},{"v":17,"t":"ولکن ریشه‌ای در خود ندارند بلکه فانی می‌باشند؛ و چون صدمه‌ای یا زحمتی به‌سبب کلام روی دهد در ساعت لغزش می‌خورند."},{"v":18,"t":"و کاشته شده در خارها آنانی می‌باشند که چون کلام راشنوند،"},{"v":19,"t":"اندیشه های دنیوی و غرور دولت وهوس چیزهای دیگر داخل شده، کلام را خفه می‌کند و بی‌ثمر می‌گردد."},{"v":20,"t":"و کاشته شده درزمین نیکو آنانند که چون کلام را شنوند آن رامی پذیرند و ثمر می‌آورند، بعضی سی و بعضی شصت و بعضی صد.»"},{"v":21,"t":"پس بدیشان گفت: «آیا چراغ را می‌آورند تازیر پیمانه‌ای یا تختی و نه بر چراغدان گذارند؟"},{"v":22,"t":"زیرا که چیزی پنهان نیست که آشکارا نگردد وهیچ‌چیز مخفی نشود، مگر تا به ظهور آید."},{"v":23,"t":"هرکه گوش شنوا دارد بشنود.»"},{"v":24,"t":"و بدیشان گفت: «باحذر باشید که چه می‌شنوید، زیرا به هر میزانی که وزن کنید به شما پیموده شود، بلکه از برای شماکه می‌شنوید افزون خواهد گشت."},{"v":25,"t":"زیرا هر‌که دارد بدو داده شود و از هر‌که ندارد آنچه نیز داردگرفته خواهد شد.»"},{"v":26,"t":"و گفت: «همچنین ملکوت خدا مانند کسی است که تخم بر زمین بیفشاند،"},{"v":27,"t":"و شب و روزبخوابد و برخیزد و تخم بروید و نمو کند. چگونه؟ او نداند."},{"v":28,"t":"زیرا که زمین به ذات خودثمر می‌آورد، اول علف، بعد خوشه، پس از آن دانه کامل در خوشه."},{"v":29,"t":"و چون ثمر رسید، فور داس را بکار می‌برد زیرا که وقت حصاد رسیده است.»"},{"v":30,"t":"و گفت: «به چه چیز ملکوت خدا را تشبیه کنیم و برای آن چه مثل بزنیم؟"},{"v":31,"t":"مثل دانه خردلی است که وقتی که آن را بر زمین کارند، کوچکترین تخمهای زمینی باشد."},{"v":32,"t":"لیکن چون کاشته شد، می‌روید و بزرگتر از جمیع بقول می‌گردد و شاخه های بزرگ می‌آورد، چنانکه مرغان هوا زیر سایه‌اش می‌توانند آشیانه گیرند.»"},{"v":33,"t":"و به مثلهای بسیار مانند اینهابقدری که استطاعت شنیدن داشتند، کلام رابدیشان بیان می‌فرمود،"},{"v":34,"t":"و بدون مثل بدیشان سخن نگفت. لیکن در خلوت، تمام معانی را برای شاگردان خود شرح می‌نمود."},{"v":35,"t":"و در همان روز وقت شام، بدیشان گفت: «به کناره دیگر عبور کنیم.»"},{"v":36,"t":"پس چون آن گروه رارخصت دادند، او را همانطوری که در کشتی بودبرداشتند و چند زورق دیگر نیز همراه او بود."},{"v":37,"t":"که ناگاه طوفانی عظیم از باد پدید آمد وامواج بر کشتی می‌خورد بقسمی که برمی گشت."},{"v":38,"t":"و او در موخر کشتی بر بالشی خفته بود. پس اورا بیدار کرده گفتند: «ای استاد، آیا تو را باکی نیست که هلاک شویم؟»"},{"v":39,"t":"در ساعت اوبرخاسته، باد را نهیب داد و به دریا گفت: «ساکن شو و خاموش باش!» که باد ساکن شده، آرامی کامل پدید آمد."},{"v":40,"t":"و ایشان را گفت: «از بهر‌چه چنین ترسانید و چون است که ایمان ندارید؟»"},{"v":41,"t":"پس بی‌نهایت ترسان شده، به یکدیگر گفتند: «این کیست که باد و دریا هم او را اطاعت می‌کنند؟»"}],"en":[{"v":1,"t":"Again he began to teach by the seaside. A great multitude was gathered to him, so that he entered into a boat in the sea and sat down. All the multitude were on the land by the sea."},{"v":2,"t":"He taught them many things in parables, and told them in his teaching,"},{"v":3,"t":"“Listen! Behold, the farmer went out to sow."},{"v":4,"t":"As he sowed, some seed fell by the road, and the birds came and devoured it."},{"v":5,"t":"Others fell on the rocky ground, where it had little soil, and immediately it sprang up, because it had no depth of soil."},{"v":6,"t":"When the sun had risen, it was scorched; and because it had no root, it withered away."},{"v":7,"t":"Others fell among the thorns, and the thorns grew up and choked it, and it yielded no fruit."},{"v":8,"t":"Others fell into the good ground and yielded fruit, growing up and increasing. Some produced thirty times, some sixty times, and some one hundred times as much.”"},{"v":9,"t":"He said, “Whoever has ears to hear, let him hear.”"},{"v":10,"t":"When he was alone, those who were around him with the twelve asked him about the parables."},{"v":11,"t":"He said to them, “To you is given the mystery of God’s Kingdom, but to those who are outside, all things are done in parables,"},{"v":12,"t":"that ‘seeing they may see and not perceive, and hearing they may hear and not understand, lest perhaps they should turn again, and their sins should be forgiven them.’”"},{"v":13,"t":"He said to them, “Don’t you understand this parable? How will you understand all of the parables?"},{"v":14,"t":"The farmer sows the word."},{"v":15,"t":"The ones by the road are the ones where the word is sown; and when they have heard, immediately Satan comes and takes away the word which has been sown in them."},{"v":16,"t":"These in the same way are those who are sown on the rocky places, who, when they have heard the word, immediately receive it with joy."},{"v":17,"t":"They have no root in themselves, but are short-lived. When oppression or persecution arises because of the word, immediately they stumble."},{"v":18,"t":"Others are those who are sown among the thorns. These are those who have heard the word,"},{"v":19,"t":"and the cares of this age, and the deceitfulness of riches, and the lusts of other things entering in choke the word, and it becomes unfruitful."},{"v":20,"t":"Those which were sown on the good ground are those who hear the word, accept it, and bear fruit, some thirty times, some sixty times, and some one hundred times.”"},{"v":21,"t":"He said to them, “Is a lamp brought to be put under a basket or under a bed? Isn’t it put on a stand?"},{"v":22,"t":"For there is nothing hidden except that it should be made known, neither was anything made secret but that it should come to light."},{"v":23,"t":"If any man has ears to hear, let him hear.”"},{"v":24,"t":"He said to them, “Take heed what you hear. With whatever measure you measure, it will be measured to you; and more will be given to you who hear."},{"v":25,"t":"For whoever has, to him more will be given; and he who doesn’t have, even that which he has will be taken away from him.”"},{"v":26,"t":"He said, “God’s Kingdom is as if a man should cast seed on the earth,"},{"v":27,"t":"and should sleep and rise night and day, and the seed should spring up and grow, though he doesn’t know how."},{"v":28,"t":"For the earth bears fruit by itself: first the blade, then the ear, then the full grain in the ear."},{"v":29,"t":"But when the fruit is ripe, immediately he puts in the sickle, because the harvest has come.”"},{"v":30,"t":"He said, “How will we liken God’s Kingdom? Or with what parable will we illustrate it?"},{"v":31,"t":"It’s like a grain of mustard seed, which, when it is sown in the earth, though it is less than all the seeds that are on the earth,"},{"v":32,"t":"yet when it is sown, grows up and becomes greater than all the herbs, and puts out great branches, so that the birds of the sky can lodge under its shadow.”"},{"v":33,"t":"With many such parables he spoke the word to them, as they were able to hear it."},{"v":34,"t":"Without a parable he didn’t speak to them; but privately to his own disciples he explained everything."},{"v":35,"t":"On that day, when evening had come, he said to them, “Let’s go over to the other side.”"},{"v":36,"t":"Leaving the multitude, they took him with them, even as he was, in the boat. Other small boats were also with him."},{"v":37,"t":"A big wind storm arose, and the waves beat into the boat, so much that the boat was already filled."},{"v":38,"t":"He himself was in the stern, asleep on the cushion; and they woke him up and asked him, “Teacher, don’t you care that we are dying?”"},{"v":39,"t":"He awoke and rebuked the wind, and said to the sea, “Peace! Be still!” The wind ceased and there was a great calm."},{"v":40,"t":"He said to them, “Why are you so afraid? How is it that you have no faith?”"},{"v":41,"t":"They were greatly afraid and said to one another, “Who then is this, that even the wind and the sea obey him?”"}],"hr":[{"v":1,"t":"I poče opet poučavati uz more. I zgrnu se k njemu silan svijet te on uđe u lađu i sjede na moru, a sve ono mnoštvo bijaše uz more, na kopnu."},{"v":2,"t":"Poučavao ih je u prispodobama mnogočemu. Govorio im u pouci:"},{"v":3,"t":"“Poslušajte! Gle, iziđe sijač sijati."},{"v":4,"t":"I dok je sijao, poneko zrno pade uz put, dođoše ptice i pozobaše ga."},{"v":5,"t":"Neko opet pade na kamenito tlo gdje nemaše dosta zemlje. Odmah izniknu jer nemaše duboke zemlje."},{"v":6,"t":"Ali kad ogranu sunce, izgorje; i jer nemaše korijenja, osuši se."},{"v":7,"t":"Neko opet pade u trnje i trnje uzraste i uguši ga te ploda ne donese."},{"v":8,"t":"Neko napokon pade u dobru zemlju i dade plod, razraste se i razmnoži, te donese: jedno tridesetostruko, jedno šezdesetostruko, jedno stostruko.”"},{"v":9,"t":"I doda: “Tko ima uši da čuje, neka čuje!”"},{"v":10,"t":"Kad bijaše nasamo, oni oko njega zajedno s dvanaestoricom pitahu ga o prispodobama."},{"v":11,"t":"I govoraše im: “Vama je dano otajstvo kraljevstva Božjega, a onima vani sve biva u prispodobama:"},{"v":12,"t":"da gledaju, gledaju - i ne vide, slušaju, slušaju - i ne razumiju, da se ne obrate pa da im se otpusti.”"},{"v":13,"t":"I kaže im: “Zar ne znate tu prispodobu? Kako ćete onda razumjeti prispodobe uopće?"},{"v":14,"t":"Sijač sije Riječ."},{"v":15,"t":"Oni uz put, gdje je Riječ posijana, jesu oni kojima, netom čuju, odmah dolazi Sotona i odnosi Riječ u njih posijanu."},{"v":16,"t":"Zasijani na tlo kamenito jesu oni koji kad čuju Riječ, odmah je s radošću prime,"},{"v":17,"t":"ali nemaju u sebi korijena, nego su nestalni: kad nastane nevolja ili progonstvo zbog Riječi, odmah se sablazne."},{"v":18,"t":"A drugi su oni u trnje zasijani. To su oni koji poslušaju Riječ,"},{"v":19,"t":"ali nadošle brige vremenite, zavodljivost bogatstva i ostale požude uguše Riječ te ona ostane bez ploda."},{"v":20,"t":"A zasijani na dobru zemlju jesu oni koji čuju i prime Riječ te urode: tridesetostruko, šezdesetostruko, stostruko."},{"v":21,"t":"I govoraše im: “Unosi li se svjetiljka da se pod posudu stavi ili pod postelju? Zar ne da se stavi na svijećnjak?"},{"v":22,"t":"Ta ništa nije zastrto, osim zato da se očituje; i ništa skriveno, osim zato da dođe na vidjelo!"},{"v":23,"t":"Ima li tko uši da čuje, neka čuje.”"},{"v":24,"t":"I govoraše im: “Pazite što slušate. Mjerom kojom mjerite mjerit će vam se. I nadodat će vam se."},{"v":25,"t":"Doista, onomu tko ima dat će se, a onomu tko nema oduzet će se i ono što ima.”"},{"v":26,"t":"I govoraše im: “Kraljevstvo je Božje kao kad čovjek baci sjeme u zemlju."},{"v":27,"t":"Spavao on ili bdio, noću i danju sjeme klija i raste - sam ne zna kako;"},{"v":28,"t":"zemlja sama od sebe donosi plod: najprije stabljiku, onda klas i napokon puno zrnja na klasu."},{"v":29,"t":"A čim plod dopusti, brže se on laća srpa jer eto žetve.”"},{"v":30,"t":"I govoraše: “Kako da prispodobimo kraljevstvo nebesko ili u kojoj da ga prispodobi iznesemo?"},{"v":31,"t":"Kao kad se gorušičino zrno posije u zemlju. Manje od svega sjemenja na zemlji,"},{"v":32,"t":"jednoć posijano, naraste i postane veće od svega povrća pa potjera velike grane te se pod sjenom njegovom gnijezde ptice nebeske.”"},{"v":33,"t":"Mnogim takvim prispodobama navješćivaše im Riječ, kako već mogahu slušati."},{"v":34,"t":"Bez prispodobe im ne govoraše, a nasamo bi svojim učenicima sve razjašnjavao."},{"v":35,"t":"Uvečer istoga dana kaže im: “Prijeđimo prijeko!”"},{"v":36,"t":"Oni otpuste mnoštvo i povezu Isusa kako već bijaše u lađi. A pratile su ga i druge lađe."},{"v":37,"t":"Najednom nasta žestoka oluja, na lađu navale valovi te su je već gotovo napunili."},{"v":38,"t":"A on na krmi spavaše na uzglavku. Probude ga i kažu mu: “Učitelju! Zar ne mariš što ginemo?”"},{"v":39,"t":"On se probudi, zaprijeti vjetru i reče moru: “Utihni! Umukni!” I smiri se vjetar i nasta velika utiha."},{"v":40,"t":"Tada im reče: “Što ste bojažljivi? Kako nemate vjere?”"},{"v":41,"t":"Oni se silno prestrašiše pa se zapitkivahu: “Tko li je ovaj da mu se i vjetar i more pokoravaju?”"}]},"5":{"fa":[{"v":1,"t":"پس به آن کناره دریا تا به‌سرزمین جدریان آمدند."},{"v":2,"t":"و چون از کشتی بیرون آمد، فی الفور شخصی که روحی پلید داشت از قبوربیرون شده، بدو برخورد."},{"v":3,"t":"که در قبور ساکن می‌بود و هیچ‌کس به زنجیرها هم نمی توانست اورا بند نماید،"},{"v":4,"t":"زیرا که بارها او را به کنده‌ها وزنجیرها بسته بودند و زنجیرها را گسیخته وکنده‌ها را شکسته بود و احدی نمی توانست او رارام نماید،"},{"v":5,"t":"و پیوسته شب وروز در کوهها وقبرها فریا می‌زد و خود را به سنگها مجروح می‌ساخت."},{"v":6,"t":"چون عیسی را از دور دید، دوان دوان آمده، او را سجده کرد،"},{"v":7,"t":"و به آواز بلندصیحه زده، گفت: «ای عیسی، پسر خدای تعالی، مرا با تو چه‌کار است؟ تو را به خدا قسم می‌دهم که مرا معذب نسازی.»"},{"v":8,"t":"زیرا بدو گفته بود: «ای روح پلید از این شخص بیرون بیا!»"},{"v":9,"t":"پس از اوپرسید: «اسم تو چیست؟» «به وی گفت: «نام من لجئون است زیرا که بسیاریم.»"},{"v":10,"t":"پس بدوالتماس بسیار نمود که ایشان را از آن سرزمین بیرون نکند."},{"v":11,"t":"و در حوالی آن کوهها، گله گرازبسیاری می‌چرید."},{"v":12,"t":"و همه دیوها از وی خواهش نموده، گفتند: «ما را به گرازها بفرست تادر آنها داخل شویم.»"},{"v":13,"t":"فور عیسی ایشان رااجازت داد. پس آن ارواح خبیث بیرون شده، به گرازان داخل گشتند و آن گله از بلندی به دریاجست و قریب بدو هزار بودند که در آب خفه شدند."},{"v":14,"t":"و خوک با نان فرار کرده، در شهر ومزرعه‌ها خبر می‌دادند و مردم بجهت دیدن آن ماجرا بیرون شتافتند."},{"v":15,"t":"و چون نزد عیسی رسیده، آن دیوانه را که لجئون داشته بود دیدند که نشسته و لباس پوشیده و عاقل گشته است، بترسیدند."},{"v":16,"t":"و آنانی که دیده بودند، سرگذشت دیوانه و گرازان را بدیشان بازگفتند."},{"v":17,"t":"پس شروع به التماس نمودند که از حدود ایشان روانه شود."},{"v":18,"t":"و چون به کشتی سوار شد، آنکه دیوانه بود ازوی استدعا نمود که با وی باشد."},{"v":19,"t":"اما عیسی وی را اجازت نداد بلکه بدو گفت: «به خانه نزدخویشان خود برو و ایشان را خبر ده از آنچه خداوند با تو کرده است و چگونه به تو رحم نموده است.»"},{"v":20,"t":"پس روانه شده، در دیکاپولس به آنچه عیسی با وی کرده، موعظه کردن آغاز نمودکه همه مردم متعجب شدند."},{"v":21,"t":"و چون عیسی باز به آنطرف، در کشتی عبور نمود، مردم بسیار بر وی جمع گشتند و برکناره دریا بود."},{"v":22,"t":"که ناگاه یکی از روسای کنیسه، یایرس نام آمد و چون او را بدید بر پایهایش افتاده،"},{"v":23,"t":"بدو التماس بسیار نموده، گفت: «نفس دخترک من به آخر رسیده. بیا و بر او دست گذار تاشفا یافته، زیست کند.»"},{"v":24,"t":"پس با او روانه شده، خلق بسیاری نیز از پی او افتاده، بر وی ازدحام می‌نمودند."},{"v":25,"t":"آنگاه زنی که مدت دوازده سال به استحاضه مبتلا می‌بود،"},{"v":26,"t":"و زحمت بسیار ازاطبای متعدد دیده و آنچه داشت صرف نموده، فایده‌ای نیافت بلکه بدتر می‌شد،"},{"v":27,"t":"چون خبرعیسی را بشنید، میان آن گروه از عقب وی آمده ردای او را لمس نمود،"},{"v":28,"t":"زیرا گفته بود: «اگرلباس وی را هم لمس کنم، هرآینه شفا یابم.»"},{"v":29,"t":"در ساعت چشمه خون او خشک شده، در تن خود فهمید که از آن بلا صحت یافته است."},{"v":30,"t":"فی الفور عیسی از خود دانست که قوتی از اوصادر گشته. پس در آن جماعت روی برگردانیده، گفت: «کیست که لباس مرا لمس نمود؟»"},{"v":31,"t":"شاگردانش بدو گفتند: «می‌بینی که مردم بر توازدحام می‌نمایند! و می‌گویی کیست که مرا لمس نمود؟ !»"},{"v":32,"t":"پس به اطراف خود می‌نگریست تا آن زن را که این کار کرده، ببیند."},{"v":33,"t":"آن زن چون دانست که به وی چه واقع شده، ترسان و لرزان آمد و نزد او به روی در‌افتاده، حقیقت امر رابالتمام به وی باز‌گفت."},{"v":34,"t":"او وی را گفت: «ای دختر، ایمانت تو را شفا داده است. به سلامتی بروو از بلای خویش رستگار باش.»"},{"v":35,"t":"او هنوز سخن می‌گفت که بعضی از خانه رئیس کنیسه آمده، گفتند: «دخترت فوت شده؛ دیگر برای چه استاد را زحمت می‌دهی؟»"},{"v":36,"t":"عیسی چون سخنی را که گفته بودند شنید، درساعت به رئیس کنیسه گفت: «مترس ایمان آور وبس!»"},{"v":37,"t":"و جز پطرس و یعقوب و یوحنا برادریعقوب، هیچ‌کس را اجازت نداد که از عقب اوبیایند."},{"v":38,"t":"پس چون به خانه رئیس کنیسه رسیدند، جمعی شوریده دید که گریه و نوحه بسیار می‌نمودند."},{"v":39,"t":"پس داخل شده، بدیشان گفت: «چرا غوغا و گریه می‌کنید؟ دختر نمرده بلکه در خواب است.»"},{"v":40,"t":"ایشان بر وی سخریه کردند لیکن او همه را بیرون کرده، پدر و مادردختر را با رفیقان خویش برداشته، به‌جایی که دختر خوابیده بود، داخل شد."},{"v":41,"t":"پس دست دختر را گرفته، به وی گفت: «طلیتا قومی.» که معنی آن این است: «ای دختر، تو را می‌گویم برخیز.»"},{"v":42,"t":"در ساعت دختر برخاسته، خرامید زیرا که دوازده ساله بود. ایشان بینهایت متعجب شدند."},{"v":43,"t":"پس ایشان را به تاکید بسیار فرمود: «کسی از این امر مطلع نشود.» و گفت تا خوراکی بدو دهند."}],"en":[{"v":1,"t":"They came to the other side of the sea, into the country of the Gadarenes."},{"v":2,"t":"When he had come out of the boat, immediately a man with an unclean spirit met him out of the tombs."},{"v":3,"t":"He lived in the tombs. Nobody could bind him any more, not even with chains,"},{"v":4,"t":"because he had been often bound with fetters and chains, and the chains had been torn apart by him, and the fetters broken in pieces. Nobody had the strength to tame him."},{"v":5,"t":"Always, night and day, in the tombs and in the mountains, he was crying out, and cutting himself with stones."},{"v":6,"t":"When he saw Jesus from afar, he ran and bowed down to him,"},{"v":7,"t":"and crying out with a loud voice, he said, “What have I to do with you, Jesus, you Son of the Most High God? I adjure you by God, don’t torment me.”"},{"v":8,"t":"For he said to him, “Come out of the man, you unclean spirit!”"},{"v":9,"t":"He asked him, “What is your name?” He said to him, “My name is Legion, for we are many.”"},{"v":10,"t":"He begged him much that he would not send them away out of the country."},{"v":11,"t":"Now on the mountainside there was a great herd of pigs feeding."},{"v":12,"t":"All the demons begged him, saying, “Send us into the pigs, that we may enter into them.”"},{"v":13,"t":"At once Jesus gave them permission. The unclean spirits came out and entered into the pigs. The herd of about two thousand rushed down the steep bank into the sea, and they were drowned in the sea."},{"v":14,"t":"Those who fed the pigs fled, and told it in the city and in the country. The people came to see what it was that had happened."},{"v":15,"t":"They came to Jesus, and saw him who had been possessed by demons sitting, clothed, and in his right mind, even him who had the legion; and they were afraid."},{"v":16,"t":"Those who saw it declared to them what happened to him who was possessed by demons, and about the pigs."},{"v":17,"t":"They began to beg him to depart from their region."},{"v":18,"t":"As he was entering into the boat, he who had been possessed by demons begged him that he might be with him."},{"v":19,"t":"He didn’t allow him, but said to him, “Go to your house, to your friends, and tell them what great things the Lord has done for you and how he had mercy on you.”"},{"v":20,"t":"He went his way, and began to proclaim in Decapolis how Jesus had done great things for him, and everyone marveled."},{"v":21,"t":"When Jesus had crossed back over in the boat to the other side, a great multitude was gathered to him; and he was by the sea."},{"v":22,"t":"Behold, one of the rulers of the synagogue, Jairus by name, came; and seeing him, he fell at his feet"},{"v":23,"t":"and begged him much, saying, “My little daughter is at the point of death. Please come and lay your hands on her, that she may be made healthy, and live.”"},{"v":24,"t":"He went with him, and a great multitude followed him, and they pressed upon him on all sides."},{"v":25,"t":"A certain woman who had a discharge of blood for twelve years,"},{"v":26,"t":"and had suffered many things by many physicians, and had spent all that she had, and was no better, but rather grew worse,"},{"v":27,"t":"having heard the things concerning Jesus, came up behind him in the crowd and touched his clothes."},{"v":28,"t":"For she said, “If I just touch his clothes, I will be made well.”"},{"v":29,"t":"Immediately the flow of her blood was dried up, and she felt in her body that she was healed of her affliction."},{"v":30,"t":"Immediately Jesus, perceiving in himself that the power had gone out from him, turned around in the crowd and asked, “Who touched my clothes?”"},{"v":31,"t":"His disciples said to him, “You see the multitude pressing against you, and you say, ‘Who touched me?’”"},{"v":32,"t":"He looked around to see her who had done this thing."},{"v":33,"t":"But the woman, fearing and trembling, knowing what had been done to her, came and fell down before him, and told him all the truth."},{"v":34,"t":"He said to her, “Daughter, your faith has made you well. Go in peace, and be cured of your disease.”"},{"v":35,"t":"While he was still speaking, people came from the synagogue ruler’s house, saying, “Your daughter is dead. Why bother the Teacher any more?”"},{"v":36,"t":"But Jesus, when he heard the message spoken, immediately said to the ruler of the synagogue, “Don’t be afraid, only believe.”"},{"v":37,"t":"He allowed no one to follow him except Peter, James, and John the brother of James."},{"v":38,"t":"He came to the synagogue ruler’s house, and he saw an uproar, weeping, and great wailing."},{"v":39,"t":"When he had entered in, he said to them, “Why do you make an uproar and weep? The child is not dead, but is asleep.”"},{"v":40,"t":"They ridiculed him. But he, having put them all out, took the father of the child, her mother, and those who were with him, and went in where the child was lying."},{"v":41,"t":"Taking the child by the hand, he said to her, “Talitha cumi!” which means, being interpreted, “Girl, I tell you, get up!”"},{"v":42,"t":"Immediately the girl rose up and walked, for she was twelve years old. They were amazed with great amazement."},{"v":43,"t":"He strictly ordered them that no one should know this, and commanded that something should be given to her to eat."}],"hr":[{"v":1,"t":"Stigoše na onu stranu mora, u kraj gerazenski."},{"v":2,"t":"Čim iziđe iz lađe, odmah mu iz grobnica pohiti u susret neki čovjek s nečistim duhom."},{"v":3,"t":"Obitavalište je imao u grobnicama. I nitko ga više nije mogao svezati ni lancima"},{"v":4,"t":"jer je već često bio i okovima i lancima svezan, ali je raskinuo okove i iskidao lance i nitko ga nije mogao ukrotiti."},{"v":5,"t":"Po cijele bi noći i dane u grobnicama i po brdima vikao i bio se kamenjem."},{"v":6,"t":"Kad izdaleka opazi Isusa, dotrči i pokloni mu se,"},{"v":7,"t":"a onda u sav glas povika: “Što ti imaš sa mnom, Isuse, Sine Boga Svevišnjega? Zaklinjem te Bogom, ne muči me!”"},{"v":8,"t":"Jer Isus mu bijaše rekao: “Iziđi, duše nečisti, iz ovoga čovjeka!”"},{"v":9,"t":"Isus ga nato upita: “Kako ti je ime?” Kaže mu: “Legija mi je ime! Ima nas mnogo!”"},{"v":10,"t":"I uporno zaklinjaše Isusa da ih ne istjera iz onoga kraja."},{"v":11,"t":"A ondje je pod brdom paslo veliko krdo svinja."},{"v":12,"t":"Zaklinjahu ga dakle: “Pošalji nas u ove svinje da u njih uđemo!”"},{"v":13,"t":"I on im dopusti. Tada iziđoše nečisti duhovi i uđoše u svinje. I krdo od oko dvije tisuće jurnu niz obronak u more i podavi se u moru."},{"v":14,"t":"Svinjari pobjegoše i razglasiše gradom i selima. A ljudi pođoše vidjeti što se dogodilo."},{"v":15,"t":"Dođu Isusu. Ugledaju opsjednutoga: sjedio je obučen i zdrave pameti - on koji ih je imao legiju. I prestraše se."},{"v":16,"t":"A očevici im razlagahu kako je to bilo s opsjednutim i ono o svinjama."},{"v":17,"t":"Tada ga stanu moliti da ode iz njihova kraja."},{"v":18,"t":"Kad je ulazio u lađu, onaj što bijaše opsjednut molio ga da bude uza nj."},{"v":19,"t":"No on mu ne dopusti, nego mu reče: “Pođi kući k svojima pa im javi što ti je učinio Gospodin, kako ti se smilovao.”"},{"v":20,"t":"On ode i poče razglašavati po Dekapolu što mu učini Isus. I svi su se divili."},{"v":21,"t":"Kad se Isus lađom ponovno prebacio prijeko, zgrnu se k njemu silan svijet."},{"v":22,"t":"Stajao je uz more. I dođe, gle, jedan od nadstojnika sinagoge, imenom Jair. Ugledavši ga, padne mu pred noge"},{"v":23,"t":"pa ga usrdno moljaše: “Kćerkica mi je na umoru! Dođi, stavi ruke na nju da ozdravi i ostane u životu!”"},{"v":24,"t":"I pođe s njima. A za njim je išao silan svijet i pritiskao ga."},{"v":25,"t":"A neka je žena dvanaest godina bolovala od krvarenja,"},{"v":26,"t":"mnogo pretrpjela od pustih liječnika, razdala sve svoje i ništa nije koristilo; štoviše, bivalo joj je sve gore."},{"v":27,"t":"Čuvši za Isusa, priđe mu među mnoštvom odostraga i dotaknu se njegove haljine."},{"v":28,"t":"Mislila je: “Dotaknem li se samo njegovih haljina, bit ću spašena.”"},{"v":29,"t":"I odmah prestane njezino krvarenje te osjeti u tijelu da je ozdravila od zla."},{"v":30,"t":"Isus odmah u sebi osjeti da je iz njega izišla sila pa se okrenu usred mnoštva i reče: “Tko se to dotaknu mojih haljina?”"},{"v":31,"t":"A učenici mu rekoše: “Ta vidiš kako te mnoštvo odasvud pritišće i još pitaš: 'Tko me se to dotaknu?'”"},{"v":32,"t":"A on zaokruži pogledom da vidi onu koja to učini."},{"v":33,"t":"Žena, sva u strahu i trepetu, svjesna onoga što joj se dogodilo, pristupi i baci se preda nj pa mu kaza sve po istini."},{"v":34,"t":"On joj reče: “Kćeri, vjera te tvoja spasila! Pođi u miru i budi zdrava od svojega zla!”"},{"v":35,"t":"Dok je Isus još govorio, eto nadstojnikovih s porukom. “Kći ti je umrla. Čemu dalje mučiti učitelja?”"},{"v":36,"t":"Isus je čuo taj razgovor, pa će nadstojniku: “Ne boj se! Samo vjeruj!”"},{"v":37,"t":"I ne dopusti da ga itko drugi prati osim Petra i Jakova i Ivana, brata Jakovljeva."},{"v":38,"t":"I dođu u kuću nadstojnikovu. Ugleda buku i one koji plakahu i naricahu u sav glas."},{"v":39,"t":"Uđe i kaže im: “Što bučite i plačete? Dijete nije umrlo, nego spava.”"},{"v":40,"t":"A oni mu se podsmjehivahu. No on ih sve izbaci, uzme sa sobom djetetova oca i majku i svoje pratioce pa uđe onamo gdje bijaše dijete."},{"v":41,"t":"Primi dijete za ruku govoreći: “Talita, kum!” što znači: “Djevojko! Zapovijedam ti, ustani!”"},{"v":42,"t":"I djevojka odmah usta i poče hodati. Bijaše joj dvanaest godina. I u tren ostadoše zapanjeni, u čudu veliku."},{"v":43,"t":"On im dobro poprijeti neka toga nitko ne dozna; i reče da djevojci dadnu jesti."}]},"6":{"fa":[{"v":1,"t":"پس از آنجا روانه شده، به وطن خویش آمد و شاگردانش از عقب او آمدند."},{"v":2,"t":"چون روز سبت رسید، در کنیسه تعلیم دادن آغاز نمودو بسیاری چون شنیدند، حیران شده گفتند: «ازکجا بدین شخص این چیزها رسیده و این چه حکمت است که به او عطا شده است که چنین معجزات از دست او صادر می‌گردد؟"},{"v":3,"t":"مگر این نیست نجار پسر مریم و برادر یعقوب و یوشا ویهودا و شمعون؟ و خواهران او اینجا نزد مانمی باشند؟» و از او لغزش خوردند."},{"v":4,"t":"عیسی ایشان را گفت: «نبی بی‌حرمت نباشد جز در وطن خود و میان خویشان و در خانه خود."},{"v":5,"t":"و در آنجاهیچ معجزه‌ای نتوانست نمود جز اینکه دستهای خود را بر چند مریض نهاده، ایشان را شفا داد."},{"v":6,"t":"واز بی‌ایمانی‌ایشان متعجب شده، در دهات آن حوالی گشته، تعلیم همی داد."},{"v":7,"t":"پس آن دوازده را پیش خوانده، شروع کرد به فرستادن ایشان جفت جفت و ایشان را بر ارواح پلید قدرت داد،"},{"v":8,"t":"و ایشان را قدغن فرمود که «جزعصا فقط، هیچ‌چیز برندارید، نه توشه‌دان و نه پول در کمربند خود،"},{"v":9,"t":"بلکه موزه‌ای در پا کنید ودو قبا در بر نکنید.»"},{"v":10,"t":"و بدیشان گفت: «در هر جاداخل خانه‌ای شوید، در آن بمانید تا از آنجا کوچ کنید."},{"v":11,"t":"و هرجا که شما را قبول نکنند و به سخن شما گوش نگیرند، از آن مکان بیرون رفته، خاک پایهای خود را بیفشانید تا بر آنها شهادتی گردد. هرآینه به شما می‌گویم حالت سدوم و غموره درروز جزا از آن شهر سهل تر خواهد بود.»"},{"v":12,"t":"پس روانه شده، موعظه کردند که توبه کنند،"},{"v":13,"t":"وبسیار دیوها را بیرون کردند و مریضان کثیر راروغن مالیده، شفا دادند."},{"v":14,"t":"و هیرودیس پادشاه شنید زیرا که اسم اوشهرت یافته بود و گفت که «یحیی تعمید‌دهنده از مردگان برخاسته است و از این جهت معجزات از او به ظهور می‌آید."},{"v":15,"t":"اما بعضی گفتند که الیاس است و بعضی گفتند که نبی‌ای است یا چون یکی از انبیا."},{"v":16,"t":"اما هیرودیس چون شنید گفت: «این همان یحیی است که من سرش را از تن جدا کردم که از مردگان برخاسته است.»"},{"v":17,"t":"زیرا که هیرودیس فرستاده، یحیی را گرفتار نموده، او رادر زندان بست بخاطر هیرودیا، زن برادر او فیلپس که او را در نکاح خویش آورده بود."},{"v":18,"t":"از آن جهت که یحیی به هیرودیس گفته بود: «نگاه داشتن زن برادرت بر تو روا نیست.»"},{"v":19,"t":"پس هیرودیا از او کینه داشته، می‌خواست اور ا به قتل رساند اما نمی توانست،"},{"v":20,"t":"زیرا که هیرودیس از یحیی می‌ترسید چونکه او را مرد عادل و مقدس می‌دانست و رعایتش می‌نمود و هرگاه از اومی شنید بسیار به عمل می‌آورد و به خوشی سخن او را اصغا می‌نمود."},{"v":21,"t":"اما چون هنگام فرصت رسید که هیرودیس در روز میلاد خودامرای خود و سرتیبان و روسای جلیل را ضیافت نمود؛"},{"v":22,"t":"و دختر هیرودیا به مجلس درآمده، رقص کرد و هیرودیس و اهل مجلس را شادنمود. پادشاه بدان دختر گفت: «آنچه خواهی ازمن بطلب تا به تو دهم.»"},{"v":23,"t":"و از برای او قسم خوردکه آنچه از من خواهی حتی نصف ملک مراهرآینه به تو عطا کنم.»"},{"v":24,"t":"او بیرون رفته، به مادرخود گفت: «چه بطلبم؟» گفت: «سر یحیی تعمیددهنده را.»"},{"v":25,"t":"در ساعت به حضور پادشاه درآمده، خواهش نموده، گفت: «می‌خواهم که الان سر یحیی تعمید‌دهنده را در طبقی به من عنایت فرمایی.»"},{"v":26,"t":"پادشاه به شدت محزون گشت، لیکن بجهت پاس قسم و خاطر اهل مجلس نخواست او را محروم نماید."},{"v":27,"t":"بی‌درنگ پادشاه جلادی فرستاده، فرمود تا سرش رابیاورد."},{"v":28,"t":"و او به زندان رفته سر او را از تن جداساخته و بر طبقی آورده، بدان دختر داد و دخترآن را به مادر خود سپرد."},{"v":29,"t":"چون شاگردانش شنیدند، آمدند و بدن او را برداشته، دفن کردند."},{"v":30,"t":"و رسولان نزد عیسی جمع شده، از آنچه کرده و تعلیم داده بودند او را خبر دادند."},{"v":31,"t":"بدیشان گفت شما به خلوت، به‌جای ویران بیایید و اندکی استراحت نمایید زیرا آمد و رفت چنان بود که فرصت نان خوردن نیز نکردند."},{"v":32,"t":"پس به تنهایی در کشتی به موضعی ویران رفتند."},{"v":33,"t":"و مردم ایشان را روانه دیده، بسیاری اورا شناختند و از جمیع شهرها بر خشکی بدان سوشتافتند و از ایشان سبقت جسته، نزد وی جمع شدند."},{"v":34,"t":"عیسی بیرون آمده، گروهی بسیار دیده، بر ایشان ترحم فرمود زیرا که چون گوسفندان بی‌شبان بودند و بسیار به ایشان تعلیم دادن گرفت."},{"v":35,"t":"و چون بیشتری از روز سپری گشت، شاگردانش نزد وی آمده، گفتند: «این مکان ویرانه است و وقت منقضی شده."},{"v":36,"t":"اینها را رخصت ده تا به اراضی و دهات این نواحی رفته، نان بجهت خود بخرند که هیچ خوراکی ندارند.»"},{"v":37,"t":"درجواب ایشان گفت: «شما ایشان را غذا دهید!» وی را گفتند: «مگر رفته، دویست دینار نان بخریم تا اینها را طعام دهیم!»"},{"v":38,"t":"بدیشان گفت: «چند نان دارید؟ رفته، تحقیق کنید.» پس دریافت کرده، گفتند: «پنج نان و دو ماهی.»"},{"v":39,"t":"آنگاه ایشان رافرمود که «همه را دسته دسته بر سبزه بنشانید.»"},{"v":40,"t":"پس صف صف، صد صد و پنجاه پنجاه نشستند."},{"v":41,"t":"و آن پنج نان و دو ماهی را گرفته، به سوی آسمان نگریسته، برکت داد و نان را پاره نموده، به شاگردان خود بسپرد تا پیش آنهابگذارند و آن دو ماهی را بر همه آنها تقسیم نمود."},{"v":42,"t":"پس جمیع خورده، سیر شدند."},{"v":43,"t":"و ازخرده های نان و ماهی، دوازده سبد پر کرده، برداشتند."},{"v":44,"t":"و خورندگان نان، قریب به پنج هزارمرد بودند."},{"v":45,"t":"فی الفور شاگردان خود را الحاح فرمود که به کشتی سوار شده، پیش از او به بیت صیدا عبورکنند تا خود آن جماعت را مرخص فرماید."},{"v":46,"t":"وچون ایشان را مرخص نمود، بجهت عبادت به فراز کوهی برآمد."},{"v":47,"t":"و چون شام شد، کشتی درمیان دریا رسید و او تنها بر خشکی بود."},{"v":48,"t":"وایشان را در راندن کشتی خسته دید زیرا که بادمخالف بر ایشان می‌وزید. پس نزدیک پاس چهارم از شب بر دریا خرامان شده، به نزد ایشان آمد و خواست از ایشان بگذرد."},{"v":49,"t":"اما چون او رابر دریا خرامان دیدند، تصور نمودند که این خیالی است. پس فریاد برآوردند،"},{"v":50,"t":"زیرا که همه او را دیده، مضطرب شدند. پس بی‌درنگ بدیشان خطاب کرده، گفت: «خاطر جمع دارید! من هستم، ترسان مباشید!»"},{"v":51,"t":"و تا نزد ایشان به کشتی سوار شد، باد ساکن گردید چنانکه بینهایت درخود متحیر و متعجب شدند،"},{"v":52,"t":"زیرا که معجزه نان را درک نکرده بودند زیرا دل ایشان سخت بود."},{"v":53,"t":"پس از دریا گذشته، به‌سرزمین جنیسارت آمده، لنگر انداختند."},{"v":54,"t":"و چون از کشتی بیرون شدند، مردم در حال او را شناختند،"},{"v":55,"t":"و در همه آن نواحی بشتاب می‌گشتند و بیماران را بر تختهانهاده، هر جا که می‌شنیدند که او در آنجا است، می‌آوردند."},{"v":56,"t":"و هر جایی که به دهات یا شهرها یا اراضی می‌رفت، مریضان را بر راهها می‌گذاردندو از او خواهش می‌نمودند که محض دامن ردای او را لمس کنند و هر‌که آن را لمس می‌کرد شفامی یافت."}],"en":[{"v":1,"t":"He went out from there. He came into his own country, and his disciples followed him."},{"v":2,"t":"When the Sabbath had come, he began to teach in the synagogue, and many hearing him were astonished, saying, “Where did this man get these things?” and, “What is the wisdom that is given to this man, that such mighty works come about by his hands?"},{"v":3,"t":"Isn’t this the carpenter, the son of Mary and brother of James, Joses, Judah, and Simon? Aren’t his sisters here with us?” So they were offended at him."},{"v":4,"t":"Jesus said to them, “A prophet is not without honor, except in his own country, and among his own relatives, and in his own house.”"},{"v":5,"t":"He could do no mighty work there, except that he laid his hands on a few sick people and healed them."},{"v":6,"t":"He marveled because of their unbelief. He went around the villages teaching."},{"v":7,"t":"He called to himself the twelve, and began to send them out two by two; and he gave them authority over the unclean spirits."},{"v":8,"t":"He commanded them that they should take nothing for their journey, except a staff only: no bread, no wallet, no money in their purse,"},{"v":9,"t":"but to wear sandals, and not put on two tunics."},{"v":10,"t":"He said to them, “Wherever you enter into a house, stay there until you depart from there."},{"v":11,"t":"Whoever will not receive you nor hear you, as you depart from there, shake off the dust that is under your feet for a testimony against them. Assuredly, I tell you, it will be more tolerable for Sodom and Gomorrah in the day of judgment than for that city!”"},{"v":12,"t":"They went out and preached that people should repent."},{"v":13,"t":"They cast out many demons, and anointed many with oil who were sick and healed them."},{"v":14,"t":"King Herod heard this, for his name had become known, and he said, “John the Baptizer has risen from the dead, and therefore these powers are at work in him.”"},{"v":15,"t":"But others said, “He is Elijah.” Others said, “He is a prophet, or like one of the prophets.”"},{"v":16,"t":"But Herod, when he heard this, said, “This is John, whom I beheaded. He has risen from the dead.”"},{"v":17,"t":"For Herod himself had sent out and arrested John and bound him in prison for the sake of Herodias, his brother Philip’s wife, for he had married her."},{"v":18,"t":"For John had said to Herod, “It is not lawful for you to have your brother’s wife.”"},{"v":19,"t":"Herodias set herself against him and desired to kill him, but she couldn’t,"},{"v":20,"t":"for Herod feared John, knowing that he was a righteous and holy man, and kept him safe. When he heard him, he did many things, and he heard him gladly."},{"v":21,"t":"Then a convenient day came when Herod on his birthday made a supper for his nobles, the high officers, and the chief men of Galilee."},{"v":22,"t":"When the daughter of Herodias herself came in and danced, she pleased Herod and those sitting with him. The king said to the young lady, “Ask me whatever you want, and I will give it to you.”"},{"v":23,"t":"He swore to her, “Whatever you ask of me, I will give you, up to half of my kingdom.”"},{"v":24,"t":"She went out and said to her mother, “What shall I ask?” She said, “The head of John the Baptizer.”"},{"v":25,"t":"She came in immediately with haste to the king and requested, “I want you to give me right now the head of John the Baptizer on a platter.”"},{"v":26,"t":"The king was exceedingly sorry, but for the sake of his oaths and of his dinner guests, he didn’t wish to refuse her."},{"v":27,"t":"Immediately the king sent out a soldier of his guard and commanded to bring John’s head; and he went and beheaded him in the prison,"},{"v":28,"t":"and brought his head on a platter, and gave it to the young lady; and the young lady gave it to her mother."},{"v":29,"t":"When his disciples heard this, they came and took up his corpse and laid it in a tomb."},{"v":30,"t":"The apostles gathered themselves together to Jesus, and they told him all things, whatever they had done, and whatever they had taught."},{"v":31,"t":"He said to them, “Come away into a deserted place, and rest awhile.” For there were many coming and going, and they had no leisure so much as to eat."},{"v":32,"t":"They went away in the boat to a deserted place by themselves."},{"v":33,"t":"They saw them going, and many recognized him and ran there on foot from all the cities. They arrived before them and came together to him."},{"v":34,"t":"Jesus came out, saw a great multitude, and he had compassion on them because they were like sheep without a shepherd; and he began to teach them many things."},{"v":35,"t":"When it was late in the day, his disciples came to him and said, “This place is deserted, and it is late in the day."},{"v":36,"t":"Send them away, that they may go into the surrounding country and villages and buy themselves bread, for they have nothing to eat.”"},{"v":37,"t":"But he answered them, “You give them something to eat.” They asked him, “Shall we go and buy two hundred denarii worth of bread and give them something to eat?”"},{"v":38,"t":"He said to them, “How many loaves do you have? Go see.” When they knew, they said, “Five, and two fish.”"},{"v":39,"t":"He commanded them that everyone should sit down in groups on the green grass."},{"v":40,"t":"They sat down in ranks, by hundreds and by fifties."},{"v":41,"t":"He took the five loaves and the two fish; and looking up to heaven, he blessed and broke the loaves, and he gave to his disciples to set before them, and he divided the two fish among them all."},{"v":42,"t":"They all ate and were filled."},{"v":43,"t":"They took up twelve baskets full of broken pieces and also of the fish."},{"v":44,"t":"Those who ate the loaves were five thousand men."},{"v":45,"t":"Immediately he made his disciples get into the boat and go ahead to the other side, to Bethsaida, while he himself sent the multitude away."},{"v":46,"t":"After he had taken leave of them, he went up the mountain to pray."},{"v":47,"t":"When evening had come, the boat was in the middle of the sea, and he was alone on the land."},{"v":48,"t":"Seeing them distressed in rowing, for the wind was contrary to them, about the fourth watch of the night he came to them, walking on the sea; and he would have passed by them,"},{"v":49,"t":"but they, when they saw him walking on the sea, supposed that it was a ghost, and cried out;"},{"v":50,"t":"for they all saw him and were troubled. But he immediately spoke with them and said to them, “Cheer up! It is I! Don’t be afraid.”"},{"v":51,"t":"He got into the boat with them; and the wind ceased, and they were very amazed among themselves, and marveled;"},{"v":52,"t":"for they hadn’t understood about the loaves, but their hearts were hardened."},{"v":53,"t":"When they had crossed over, they came to land at Gennesaret and moored to the shore."},{"v":54,"t":"When they had come out of the boat, immediately the people recognized him,"},{"v":55,"t":"and ran around that whole region, and began to bring those who were sick on their mats to where they heard he was."},{"v":56,"t":"Wherever he entered—into villages, or into cities, or into the country—they laid the sick in the marketplaces and begged him that they might just touch the fringe of his garment; and as many as touched him were made well."}],"hr":[{"v":1,"t":"I otišavši odande, dođe u svoj zavičaj. A doprate ga učenici."},{"v":2,"t":"I kada dođe subota, poče učiti u sinagogi. I mnogi što su ga slušali preneraženi govorahu: “Odakle to ovome? Kakva li mu je mudrost dana? I kakva se to silna djela događaju po njegovim rukama?"},{"v":3,"t":"Nije li ovo drvodjelja, sin Marijin, i brat Jakovljev, i Josipov, i Judin, i Šimunov? I nisu li mu sestre ovdje među nama?” I sablažnjavahu se o njega."},{"v":4,"t":"A Isus im govoraše: “Nije prorok bez časti doli u svom zavičaju i među rodbinom i u svom domu.”"},{"v":5,"t":"I ne mogaše ondje učiniti ni jedno čudo, osim što ozdravi nekoliko nemoćnika stavivši ruke na njih."},{"v":6,"t":"I čudio se njihovoj nevjeri. Obilazio je selima uokolo i naučavao."},{"v":7,"t":"Dozva dvanaestoricu te ih poče slati dva po dva dajući im vlast nad nečistim dusima."},{"v":8,"t":"I zapovjedi im da na put ne nose ništa osim štapa: ni kruha, ni torbe, ni novaca o pojasu,"},{"v":9,"t":"nego da nose samo sandale i da ne oblače dviju haljina."},{"v":10,"t":"I govoraše im: “Kad uđete gdje u kuću, u njoj ostanite dok ne odete odande."},{"v":11,"t":"Ako vas gdje ne prime te vas ne poslušaju, iziđite odande i otresite prah ispod svojih nogu njima za svjedočanstvo.”"},{"v":12,"t":"Otišavši, propovijedali su obraćenje,"},{"v":13,"t":"izgonili mnoge zloduhe i mnoge su nemoćnike mazali uljem i oni su ozdravljali."},{"v":14,"t":"Dočuo to i kralj Herod jer se razglasilo Isusovo ime te se govorilo: “Ivan Krstitelj uskrsnuo od mrtvih i zato čudesne sile djeluju u njemu.”"},{"v":15,"t":"A drugi govorahu: “Ilija je!” Treći opet: “Prorok, kao jedan od proroka.”"},{"v":16,"t":"Herod pak na to govoraše: “Uskrsnu Ivan kojemu ja odrubih glavu.”"},{"v":17,"t":"Herod doista bijaše dao uhititi Ivana i svezati ga u tamnici zbog Herodijade, žene brata svoga Filipa, kojom se bio oženio."},{"v":18,"t":"Budući da je Ivan govorio Herodu: “Ne smiješ imati žene brata svojega!”,"},{"v":19,"t":"Herodijada ga mrzila i htjela ga ubiti, ali nije mogla"},{"v":20,"t":"jer se Herod bojao Ivana; znao je da je on čovjek pravedan i svet pa ga je štitio. I kad god bi ga slušao, uvelike bi se zbunio, a rado ga je slušao."},{"v":21,"t":"I dođe zgodan dan kad Herod o svom rođendanu priredi gozbu svojim velikašima, časnicima i prvacima galilejskim."},{"v":22,"t":"Uđe kći Herodijadina i zaplesa. Svidje se Herodu i sustolnicima. Kralj reče djevojci: “Zaišti od mene što god hoćeš i dat ću ti!”"},{"v":23,"t":"I zakle joj se: “Što god zaišteš od mene, dat ću ti, pa bilo to i pol mojega kraljevstva.”"},{"v":24,"t":"Ona iziđe pa će svojoj materi: “Što da zaištem?” A ona će: “Glavu Ivana Krstitelja!”"},{"v":25,"t":"I odmah žurno uđe kralju te zaište: “Hoću da mi odmah dadeš na pladnju glavu Ivana Krstitelja!”"},{"v":26,"t":"Ožalosti se kralj, ali zbog zakletve i sustolnika na htjede je odbiti."},{"v":27,"t":"Kralj odmah posla krvnika i naredi da donese glavu Ivanovu. On ode, odrubi mu glavu u tamnici,"},{"v":28,"t":"donese je na pladnju i dade je djevojci, a djevojka materi."},{"v":29,"t":"Kad za to dočuše Ivanovi učenici, dođu, uzmu njegovo tijelo i polože ga u grob."},{"v":30,"t":"Uto se apostoli skupe oko Isusa i izvijeste ga o svemu što su činili i naučavali."},{"v":31,"t":"I reče im: “Hajdete i vi u osamu na samotno mjesto, i otpočinite malo.” Jer mnogo je svijeta dolazilo i odlazilo pa nisu imali kada ni jesti."},{"v":32,"t":"Otploviše dakle lađom na samotno mjesto, u osamu."},{"v":33,"t":"No kad su odlazili, mnogi ih vidješe i prepoznaše te se pješice iz svih gradova strčaše onamo i pretekoše ih."},{"v":34,"t":"Kad iziđe, vidje silan svijet i sažali mu se jer bijahu kao ovce bez pastira pa ih stane poučavati u mnogočemu."},{"v":35,"t":"A u kasni već sat pristupe mu učenici pa mu reknu: “Pust je ovo kraj i već je kasno."},{"v":36,"t":"Otpusti ih da odu po okolnim zaseocima i selima i kupe sebi što za jelo.”"},{"v":37,"t":"No on im odgovori: “Podajte im vi jesti.” Kažu mu: “Da pođemo i kupimo za dvjesta denara kruha pa da im damo jesti?”"},{"v":38,"t":"A on će im: “Koliko kruhova imate? Idite i vidite!” Pošto izvidješe, kažu: “Pet, i dvije ribe.”"},{"v":39,"t":"I zapovjedi im da sve, u skupinama, posjedaju po zelenoj travi."},{"v":40,"t":"I pružiše se po sto i po pedeset na svaku lijehu."},{"v":41,"t":"On uze pet kruhova i dvije ribe, pogleda na nebo, izreče blagoslov pa razlomi kruhove i davaše učenicima da posluže ljude. Tako i dvije ribe razdijeli svima."},{"v":42,"t":"I jeli su svi i nasitili se."},{"v":43,"t":"I od ulomaka nakupiše dvanaest punih košara, a i od riba."},{"v":44,"t":"A jelo je pet tisuća muškaraca."},{"v":45,"t":"On odmah prisili učenike da uđu u lađu i da se prebace prijeko, prema Betsaidi, dok on otpusti mnoštvo."},{"v":46,"t":"I pošto se rasta s ljudima, otiđe u goru da se pomoli."},{"v":47,"t":"Uvečer pak lađa bijaše posred mora, a on sam na kraju."},{"v":48,"t":"Vidjevši kako se muče veslajući, jer im bijaše protivan vjetar, oko četvrte noćne straže dođe k njima hodeći po moru. I htjede ih mimoići."},{"v":49,"t":"A oni, vidjevši kako hodi po moru, pomisliše da je utvara pa kriknuše."},{"v":50,"t":"Jer svi su ga vidjeli i prestrašili se. A on im odmah progovori: “Hrabro samo! Ja sam! Ne bojte se!”"},{"v":51,"t":"I uziđe k njima u lađu, a vjetar utihnu. I veoma se, prekomjerno, snebivahu;"},{"v":52,"t":"još ne shvatiše ono o kruhovima, nego im srce bijaše stvrdnuto."},{"v":53,"t":"Pošto doploviše na kraj, dođu u Genezaret i pristanu."},{"v":54,"t":"Kad iziđu iz lađe, ljudi ga odmah prepoznaju"},{"v":55,"t":"pa oblete sav onaj kraj. I počnu donositi na nosilima bolesnike onamo gdje bi čuli da se on nalazi."},{"v":56,"t":"I kamo bi god ulazio - u sela, u gradove, u zaseoke - po trgovima bi stavljali bolesnike i molili ga da se dotaknu makar skuta njegove haljine. I koji bi ga se god dotakli, ozdravljali bi."}]},"7":{"fa":[{"v":1,"t":"و فریسیان و بعضی کاتبان از اورشلیم آمده، نزد او جمع شدند."},{"v":2,"t":"چون بعضی ازشاگردان او را دیدند که با دستهای ناپاک یعنی ناشسته نان می‌خورند، ملامت نمودند،"},{"v":3,"t":"زیرا که فریسیان و همه یهود تمسک به تقلید مشایخ نموده، تا دستها را بدقت نشویند غذا نمی خورند،"},{"v":4,"t":"و چون از بازارها آیند تا نشویند چیزی نمی خورند و بسیار رسوم دیگر هست که نگاه می‌دارند چون شستن پیاله‌ها و آفتابه‌ها و ظروف مس و کرسیها."},{"v":5,"t":"پس فریسیان و کاتبان از اوپرسیدند: «چون است که شاگردان تو به تقلیدمشایخ سلوک نمی نمایند بلکه به‌دستهای ناپاک نان می‌خورند؟»"},{"v":6,"t":"در جواب ایشان گفت: «نیکو اخبار نموداشعیا درباره شما‌ای ریاکاران، چنانکه مکتوب است: این قوم به لبهای خود مرا حرمت می‌دارندلیکن دلشان از من دور است."},{"v":7,"t":"پس مرا عبث عبادت می‌نمایند زیرا که رسوم انسانی را به‌جای فرایض تعلیم می‌دهند،"},{"v":8,"t":"زیرا حکم خدا را ترک کرده، تقلید انسان را نگاه می‌دارند، چون شستن آفتابه‌ها و پیاله‌ها و چنین رسوم دیگر بسیار بعمل می‌آورید.»"},{"v":9,"t":"پس بدیشان گفت که «حکم خدا رانیکو باطل ساخته‌اید تا تقلید خود را محکم بدارید."},{"v":10,"t":"از اینجهت که موسی گفت پدر و مادرخود را حرمت دار و هر‌که پدر یا مادر را دشنام دهد، البته هلاک گردد."},{"v":11,"t":"لیکن شما می‌گویید که هرگاه شخصی به پدر یا مادر خود گوید: “آنچه ازمن نفع یابی قربان یعنی هدیه برای خداست “"},{"v":12,"t":"وبعد از این او را اجازت نمی دهید که پدر یا مادرخود را هیچ خدمت کند."},{"v":13,"t":"پس کلام خدا را به تقلیدی که خود جاری ساخته‌اید، باطل می‌سازید و کارهای مثل این بسیار به‌جامی آورید.»"},{"v":14,"t":"پس آن جماعت را پیش خوانده، بدیشان گفت: «همه شما به من گوش دهید و فهم کنید."},{"v":15,"t":"هیچ‌چیز نیست که از بیرون آدم داخل او گشته، بتواند او را نجس سازد بلکه آنچه از درونش صادر شود آن است که آدم را ناپاک می‌سازد."},{"v":16,"t":"هر‌که گوش شنوا دارد بشنود.»"},{"v":17,"t":"و چون از نزد جماعت به خانه در‌آمد، شاگردانش معنی مثل را از او پرسیدند."},{"v":18,"t":"بدیشان گفت: «مگر شما نیز همچنین بی‌فهم هستید ونمی دانید که آنچه از بیرون داخل آدم می‌شود، نمی تواند او را ناپاک سازد،"},{"v":19,"t":"زیرا که داخل دلش نمی شود بلکه به شکم می‌رود و خارج می‌شود به مزبله‌ای که این همه خوراک را پاک می‌کند.»"},{"v":20,"t":"وگفت: «آنچه از آدم بیرون آید، آن است که انسان را ناپاک می‌سازد،"},{"v":21,"t":"زیرا که از درون دل انسان صادر می‌شود، خیالات بد و زنا و فسق و قتل ودزدی"},{"v":22,"t":"و طمع و خباثت و مکر و شهوت‌پرستی و چشم بد و کفر و غرور و جهالت."},{"v":23,"t":"تمامی این چیزهای بد از درون صادر می‌گردد و آدم را ناپاک می‌گرداند.»"},{"v":24,"t":"پس از آنجا برخاسته به حوالی صور وصیدون رفته، به خانه درآمد و خواست که هیچ‌کس مطلع نشود، لیکن نتوانست مخفی بماند،"},{"v":25,"t":"از آنرو که زنی که دخترک وی روح پلیدداشت، چون خبر او را بشنید، فور آمده برپایهای او افتاد."},{"v":26,"t":"و او زن یونانی از اهل فینیقیه صوریه بود. پس از وی استدعا نمود که دیو را ازدخترش بیرون کند."},{"v":27,"t":"عیسی وی را گفت: «بگذار اول فرزندان سیر شوند زیرا نان فرزندان راگرفتن و پیش سگان انداختن نیکو نیست.»"},{"v":28,"t":"آن زن در جواب وی گفت: «بلی خداوندا، زیرا سگان نیز پس خرده های فرزندان را از زیر سفره می‌خورند.»"},{"v":29,"t":"وی را گفت؛ «بجهت این سخن برو که دیو از دخترت بیرون شد.»"},{"v":30,"t":"پس چون به خانه خود رفت، دیو را بیرون شده و دختر را بربستر خوابیده یافت."},{"v":31,"t":"و باز از نواحی صور روانه شده، از راه صیدون در میان حدود دیکاپولس به دریای جلیل آمد."},{"v":32,"t":"آنگاه کری را که لکنت زبان داشت نزد وی آورده، التماس کردند که دست بر او گذارد."},{"v":33,"t":"پس او را از میان جماعت به خلوت برده، انگشتان خود را در گوشهای او گذاشت و آب دهان انداخته، زبانش را لمس نمود؛"},{"v":34,"t":"و به سوی آسمان نگریسته، آهی کشید و بدو گفت: «افتح!» یعنی باز شو"},{"v":35,"t":"در ساعت گوشهای او گشاده وعقده زبانش حل شده، به درستی تکلم نمود."},{"v":36,"t":"پس ایشان را قدغن فرمود که هیچ‌کس را خبرندهند؛ لیکن چندان‌که بیشتر ایشان را قدغن نمود، زیادتر او را شهرت دادند."},{"v":37,"t":"و بینهایت متحیر گشته می‌گفتند: «همه کارها را نیکوکرده است؛ کران را شنوا و گنگان را گویامی گرداند!»"}],"en":[{"v":1,"t":"Then the Pharisees and some of the scribes gathered together to him, having come from Jerusalem."},{"v":2,"t":"Now when they saw some of his disciples eating bread with defiled, that is unwashed, hands, they found fault."},{"v":3,"t":"(For the Pharisees and all the Jews don’t eat unless they wash their hands and forearms, holding to the tradition of the elders."},{"v":4,"t":"They don’t eat when they come from the marketplace unless they bathe themselves, and there are many other things which they have received to hold to: washings of cups, pitchers, bronze vessels, and couches.)"},{"v":5,"t":"The Pharisees and the scribes asked him, “Why don’t your disciples walk according to the tradition of the elders, but eat their bread with unwashed hands?”"},{"v":6,"t":"He answered them, “Well did Isaiah prophesy of you hypocrites, as it is written, ‘This people honors me with their lips, but their heart is far from me."},{"v":7,"t":"They worship me in vain, teaching as doctrines the commandments of men.’"},{"v":8,"t":"“For you set aside the commandment of God, and hold tightly to the tradition of men—the washing of pitchers and cups, and you do many other such things.”"},{"v":9,"t":"He said to them, “Full well do you reject the commandment of God, that you may keep your tradition."},{"v":10,"t":"For Moses said, ‘Honor your father and your mother;’ and, ‘He who speaks evil of father or mother, let him be put to death.’"},{"v":11,"t":"But you say, ‘If a man tells his father or his mother, “Whatever profit you might have received from me is Corban,”’” that is to say, given to God,"},{"v":12,"t":"“then you no longer allow him to do anything for his father or his mother,"},{"v":13,"t":"making void the word of God by your tradition which you have handed down. You do many things like this.”"},{"v":14,"t":"He called all the multitude to himself and said to them, “Hear me, all of you, and understand."},{"v":15,"t":"There is nothing from outside of the man that going into him can defile him; but the things which proceed out of the man are those that defile the man."},{"v":16,"t":"If anyone has ears to hear, let him hear!”"},{"v":17,"t":"When he had entered into a house away from the multitude, his disciples asked him about the parable."},{"v":18,"t":"He said to them, “Are you also without understanding? Don’t you perceive that whatever goes into the man from outside can’t defile him,"},{"v":19,"t":"because it doesn’t go into his heart, but into his stomach, then into the latrine, making all foods clean?”"},{"v":20,"t":"He said, “That which proceeds out of the man, that defiles the man."},{"v":21,"t":"For from within, out of the hearts of men, proceed evil thoughts, adulteries, sexual sins, murders, thefts,"},{"v":22,"t":"covetings, wickedness, deceit, lustful desires, an evil eye, blasphemy, pride, and foolishness."},{"v":23,"t":"All these evil things come from within and defile the man.”"},{"v":24,"t":"From there he arose and went away into the borders of Tyre and Sidon. He entered into a house and didn’t want anyone to know it, but he couldn’t escape notice."},{"v":25,"t":"For a woman whose little daughter had an unclean spirit, having heard of him, came and fell down at his feet."},{"v":26,"t":"Now the woman was a Greek, a Syrophoenician by race. She begged him that he would cast the demon out of her daughter."},{"v":27,"t":"But Jesus said to her, “Let the children be filled first, for it is not appropriate to take the children’s bread and throw it to the dogs.”"},{"v":28,"t":"But she answered him, “Yes, Lord. Yet even the dogs under the table eat the children’s crumbs.”"},{"v":29,"t":"He said to her, “For this saying, go your way. The demon has gone out of your daughter.”"},{"v":30,"t":"She went away to her house, and found the child having been laid on the bed, with the demon gone out."},{"v":31,"t":"Again he departed from the borders of Tyre and Sidon, and came to the sea of Galilee through the middle of the region of Decapolis."},{"v":32,"t":"They brought to him one who was deaf and had an impediment in his speech. They begged him to lay his hand on him."},{"v":33,"t":"He took him aside from the multitude privately and put his fingers into his ears; and he spat and touched his tongue."},{"v":34,"t":"Looking up to heaven, he sighed, and said to him, “Ephphatha!” that is, “Be opened!”"},{"v":35,"t":"Immediately his ears were opened, and the impediment of his tongue was released, and he spoke clearly."},{"v":36,"t":"He commanded them that they should tell no one, but the more he commanded them, so much the more widely they proclaimed it."},{"v":37,"t":"They were astonished beyond measure, saying, “He has done all things well. He makes even the deaf hear and the mute speak!”"}],"hr":[{"v":1,"t":"Skupe se oko njega farizeji i neki od pismoznanaca koji dođoše iz Jeruzalema."},{"v":2,"t":"I opaze da neki njegovi učenici jedu kruh nečistih, to jest neopranih ruku."},{"v":3,"t":"A farizeji i svi Židovi ne jedu ako prije temeljito ne operu ruke; drže se predaje starih."},{"v":4,"t":"Niti s trga što jedu ako prije ne operu. Mnogo toga još ima što zbog predaje drže: pranje čaša, vrčeva i lonaca."},{"v":5,"t":"Zato farizeji i pismoznanci upitaju Isusa: “Zašto tvoji učenici ne postupaju po predaji starih, nego nečistih ruku blaguju?”"},{"v":6,"t":"A on im reče: “Dobro prorokova Izaija o vama, licemjeri, kad napisa: Ovaj me narod usnama časti, a srce mu je daleko od mene."},{"v":7,"t":"Uzalud me štuju naučavajući nauke - uredbe ljudske."},{"v":8,"t":"Napustili ste zapovijed Božju, a držite se predaje ljudske.”"},{"v":9,"t":"Još im govoraše: “Lijepo! Dokidate Božju zapovijed da biste sačuvali svoju predaju."},{"v":10,"t":"Mojsije doista reče: Poštuj oca svoga i majku svoju. I: Tko prokune oca ili majku, smrću neka se kazni."},{"v":11,"t":"A vi velite: 'Rekne li tko ocu ili majci: Pomoć koja te od mene ide neka bude 'korban', to jest sveti dar',"},{"v":12,"t":"takvome više ne dopuštate ništa učiniti za oca ili majku."},{"v":13,"t":"Tako dokidate riječ Božju svojom predajom, koju sami sebi predadoste. I još štošta tomu slično činite.”"},{"v":14,"t":"Tada ponovno dozove mnoštvo i stane govoriti: “Poslušajte me svi i razumijte!"},{"v":15,"t":"Ništa što izvana ulazi u čovjeka ne može ga onečistiti, nego što iz čovjeka izlazi - to ga onečišćuje."},{"v":16,"t":"Tko ima uši da čuje, neka čuje!”"},{"v":17,"t":"I kad od mnoštva uđe u kuću, upitaše ga učenici za prispodobu."},{"v":18,"t":"I reče im: “Tako? Ni vi ne razumijete? Ne shvaćate li da čovjeka ne može onečistiti što u nj ulazi"},{"v":19,"t":"jer mu ne ulazi u srce, nego u utrobu te izlazi u zahod?” Tako on očisti sva jela."},{"v":20,"t":"Još dometnu: “Što iz čovjeka izlazi, te onečišćuje čovjeka."},{"v":21,"t":"Ta iznutra, iz srca čovječjega, izlaze zle namisli, bludništva, krađe, ubojstva,"},{"v":22,"t":"preljubi, lakomstva, opakosti, prijevara, razuzdanost, zlo oko, psovka, uznositost, bezumlje."},{"v":23,"t":"Sva ta zla iznutra izlaze i onečišćuju čovjeka.”"},{"v":24,"t":"Odande otiđe u kraj tirski. I uđe u neku kuću. Htio je da nitko ne sazna, ali se nije mogao sakriti,"},{"v":25,"t":"nego odmah doču žena koje kćerkica imaše duha nečistoga. Ona dođe i pade mu pred noge."},{"v":26,"t":"A žena bijaše Grkinja, Sirofeničanka rodom. I moljaše ga da joj iz kćeri istjera zloduha."},{"v":27,"t":"A on joj govoraše: “Pusti da se prije nasite djeca! Ne priliči uzeti kruh djeci i baciti ga psićima.”"},{"v":28,"t":"A ona će mu: “Da, Gospodine! Ali i psići ispod stola jedu od mrvica dječjih.”"},{"v":29,"t":"Reče joj: “Zbog te riječi idi, izišao je iz tvoje kćeri zloduh.”"},{"v":30,"t":"I ode kući te nađe dijete gdje leži na postelji, a zloduh je bio izišao."},{"v":31,"t":"Zatim se ponovno vrati iz krajeva tirskih pa preko Sidona dođe Galilejskom moru, u krajeve dekapolske."},{"v":32,"t":"Donesu mu nekoga gluhog mucavca pa ga zamole da stavi na nj ruku."},{"v":33,"t":"On ga uzme nasamo od mnoštva, utisne svoje prste u njegove uši, zatim pljune i dotakne se njegova jezika."},{"v":34,"t":"Upravi pogled u nebo, uzdahne i kaže mu: “Effata!” - to će reći: “Otvori se!”"},{"v":35,"t":"I odmah mu se otvoriše uši i razdriješi spona jezika te stade govoriti razgovijetno."},{"v":36,"t":"A Isus im zabrani da nikome ne kazuju. No što im je on više branio, oni su to više razglašavali"},{"v":37,"t":"i preko svake mjere zadivljeni govorili: “Dobro je sve učinio! Gluhima daje čuti, nijemima govoriti!”"}]},"8":{"fa":[{"v":1,"t":"و در آن ایام باز جمعیت، بسیار شده و خوراکی نداشتند. عیسی شاگردان خود راپیش طلبیده، به ایشان گفت:"},{"v":2,"t":"«بر این گروه دلم بسوخت زیرا الان سه روز است که با من می‌باشندو هیچ خوراک ندارند."},{"v":3,"t":"و هرگاه ایشان را گرسنه به خانه های خود برگردانم، هرآینه در راه ضعف کنند، زیرا که بعضی از ایشان از راه دور آمده‌اند.»"},{"v":4,"t":"شاگردانش وی را جواب دادند: «از کجا کسی می‌تواند اینها را در این صحرا از نان سیر گرداند؟»"},{"v":5,"t":"از ایشان پرسید: «چند نان دارید؟» گفتند: «هفت.»"},{"v":6,"t":"پس جماعت را فرمود تا بر زمین بنشینند؛ و آن هفت نان را گرفته، شکر نمود و پاره کرده، به شاگردان خود داد تا پیش مردم گذارند. پس نزد آن گروه نهادند."},{"v":7,"t":"و چند ماهی کوچک نیز داشتند. آنها را نیز برکت داده، فرمود تا پیش ایشان نهند."},{"v":8,"t":"پس خورده، سیر شدند و هفت زنبیل پر از پاره های باقی‌مانده برداشتند."},{"v":9,"t":"و عددخورندگان قریب به چهار هزار بود. پس ایشان رامرخص فرمود."},{"v":10,"t":"و بی‌درنگ با شاگردان به کشتی سوار شده، به نواحی دلمانوته آمد."},{"v":11,"t":"و فریسیان بیرون آمده، با وی به مباحثه شروع کردند. و از راه امتحان آیتی آسمانی از او خواستند."},{"v":12,"t":"او از دل آهی کشیده، گفت: «از برای چه این فرقه آیتی می‌خواهند؟ هرآینه به شما می‌گویم آیتی بدین فرقه عطا نخواهد شد.»"},{"v":13,"t":"پس ایشان را گذارد و باز به کشتی سوارشده، به کناره دیگر عبور نمود."},{"v":14,"t":"و فراموش کردند که نان بردارند و با خود در کشتی جز یک نان نداشتند."},{"v":15,"t":"آنگاه ایشان را قدغن فرمود که «باخبر باشید و از خمیر مایه فریسیان و خمیرمایه هیرودیس احتیاط کنید!»"},{"v":16,"t":"ایشان با خوداندیشیده، گفتند: «از آن است که نان نداریم.»"},{"v":17,"t":"عیسی فهم کرده، بدیشان گفت: «چرا فکرمی کنید از آنجهت که نان ندارید؟ آیا هنوزنفهمیده و درک نکرده‌اید و تا حال دل شما سخت است؟"},{"v":18,"t":"آیا چشم داشته نمی بینید و گوش داشته نمی شنوید و به یاد ندارید؟"},{"v":19,"t":"وقتی که پنج نان را برای پنج هزار نفر پاره کردم، چند سبدپر از پاره‌ها برداشتید؟» بدو گفتند: «دوازده.»"},{"v":20,"t":"«و وقتی که هفت نان را بجهت چهار هزار کس؛ پس زنبیل پر از ریزه‌ها برداشتید؟» گفتندش: «هفت.»"},{"v":21,"t":"پس بدیشان گفت: «چرا نمی فهمید؟»"},{"v":22,"t":"چون به بیت صیدا آمد، شخصی کور را نزد او آوردند و التماس نمودند که او را لمس نماید."},{"v":23,"t":"پس دست آن کور را گرفته، او را از قریه بیرون برد و آب دهان بر چشمان او افکنده، و دست بر اوگذارده از او پرسید که «چیزی می‌بینی؟»"},{"v":24,"t":"اوبالا نگریسته، گفت: «مردمان را خرامان، چون درختها می‌بینم.»"},{"v":25,"t":"پس بار دیگر دستهای خودرا بر چشمان او گذارده، او را فرمود تا بالانگریست و صحیح گشته، همه‌چیز را به خوبی دید."},{"v":26,"t":"پس او را به خانه‌اش فرستاده، گفت: «داخل ده مشو و هیچ‌کس را در آن جا خبر مده.»"},{"v":27,"t":"و عیسی با شاگردان خود به دهات قیصریه فیلپس رفت. و در راه از شاگردانش پرسیده، گفت که «مردم مرا که می‌دانند؟»"},{"v":28,"t":"ایشان جواب دادند که «یحیی تعمید‌دهنده و بعضی الیاس وبعضی یکی از انبیا.»"},{"v":29,"t":"او از ایشان پرسید: «شمامرا که می‌دانید؟» پطرس در جواب او گفت: «تومسیح هستی.»"},{"v":30,"t":"پس ایشان را فرمود که «هیچ‌کس را از او خبر ندهند.»"},{"v":31,"t":"آنگاه ایشان را تعلیم دادن آغاز کرد که «لازم است پسر انسان بسیار زحمت کشد و ازمشایخ و روسای کهنه و کاتبان رد شود و کشته شده، بعد از سه روز برخیزد.»"},{"v":32,"t":"و چون این کلام را علانیه فرمود، پطرس او را گرفته، به منع کردن شروع نمود."},{"v":33,"t":"اما او برگشته، به شاگردان خودنگریسته، پطرس را نهیب داد و گفت: «ای شیطان از من دور شو، زیرا امور الهی را اندیشه نمی کنی بلکه چیزهای انسانی را.»"},{"v":34,"t":"پس مردم را با شاگردان خود خوانده، گفت: «هر‌که خواهد از عقب من آید، خویشتن را انکارکند و صلیب خود را برداشته، مرا متابعت نماید."},{"v":35,"t":"زیرا هر‌که خواهد جان خود را نجات دهد، آن را هلاک سازد؛ و هر‌که جان خود را بجهت من وانجیل بر باد دهد آن را برهاند."},{"v":36,"t":"زیراکه شخص را چه سود دارد هر گاه تمام دنیا را ببرد و نفس خود را ببازد؟"},{"v":37,"t":"یا آنکه آدمی چه چیز را به عوض جان خود بدهد؟"},{"v":38,"t":"زیرا هر‌که در این فرقه زناکار و خطاکار از من و سخنان من شرمنده شود، پسر انسان نیز وقتی که با فرشتگان مقدس درجلال پدر خویش آید، از او شرمنده خواهدگردید.»"}],"en":[{"v":1,"t":"In those days, when there was a very great multitude, and they had nothing to eat, Jesus called his disciples to himself and said to them,"},{"v":2,"t":"“I have compassion on the multitude, because they have stayed with me now three days and have nothing to eat."},{"v":3,"t":"If I send them away fasting to their home, they will faint on the way, for some of them have come a long way.”"},{"v":4,"t":"His disciples answered him, “From where could one satisfy these people with bread here in a deserted place?”"},{"v":5,"t":"He asked them, “How many loaves do you have?” They said, “Seven.”"},{"v":6,"t":"He commanded the multitude to sit down on the ground, and he took the seven loaves. Having given thanks, he broke them and gave them to his disciples to serve, and they served the multitude."},{"v":7,"t":"They also had a few small fish. Having blessed them, he said to serve these also."},{"v":8,"t":"They ate and were filled. They took up seven baskets of broken pieces that were left over."},{"v":9,"t":"Those who had eaten were about four thousand. Then he sent them away."},{"v":10,"t":"Immediately he entered into the boat with his disciples and came into the region of Dalmanutha."},{"v":11,"t":"The Pharisees came out and began to question him, seeking from him a sign from heaven and testing him."},{"v":12,"t":"He sighed deeply in his spirit and said, “Why does this generation seek a sign? Most certainly I tell you, no sign will be given to this generation.”"},{"v":13,"t":"He left them, and again entering into the boat, departed to the other side."},{"v":14,"t":"They forgot to take bread; and they didn’t have more than one loaf in the boat with them."},{"v":15,"t":"He warned them, saying, “Take heed: beware of the yeast of the Pharisees and the yeast of Herod.”"},{"v":16,"t":"They reasoned with one another, saying, “It’s because we have no bread.”"},{"v":17,"t":"Jesus, perceiving it, said to them, “Why do you reason that it’s because you have no bread? Don’t you perceive yet or understand? Is your heart still hardened?"},{"v":18,"t":"Having eyes, don’t you see? Having ears, don’t you hear? Don’t you remember?"},{"v":19,"t":"When I broke the five loaves among the five thousand, how many baskets full of broken pieces did you take up?” They told him, “Twelve.”"},{"v":20,"t":"“When the seven loaves fed the four thousand, how many baskets full of broken pieces did you take up?” They told him, “Seven.”"},{"v":21,"t":"He asked them, “Don’t you understand yet?”"},{"v":22,"t":"He came to Bethsaida. They brought a blind man to him and begged him to touch him."},{"v":23,"t":"He took hold of the blind man by the hand, and brought him out of the village. When he had spat on his eyes, and laid his hands on him, he asked him if he saw anything."},{"v":24,"t":"He looked up, and said, “I see men, but I see them like walking trees.”"},{"v":25,"t":"Then again he laid his hands on his eyes. He looked intently, and was restored, and saw everyone clearly."},{"v":26,"t":"He sent him away to his house, saying, “Don’t enter into the village, nor tell anyone in the village.”"},{"v":27,"t":"Jesus went out, with his disciples, into the villages of Caesarea Philippi. On the way he asked his disciples, “Who do men say that I am?”"},{"v":28,"t":"They told him, “John the Baptizer, and others say Elijah, but others, one of the prophets.”"},{"v":29,"t":"He said to them, “But who do you say that I am?” Peter answered, “You are the Christ.”"},{"v":30,"t":"He commanded them that they should tell no one about him."},{"v":31,"t":"He began to teach them that the Son of Man must suffer many things, and be rejected by the elders, the chief priests, and the scribes, and be killed, and after three days rise again."},{"v":32,"t":"He spoke to them openly. Peter took him and began to rebuke him."},{"v":33,"t":"But he, turning around and seeing his disciples, rebuked Peter, and said, “Get behind me, Satan! For you have in mind not the things of God, but the things of men.”"},{"v":34,"t":"He called the multitude to himself with his disciples and said to them, “Whoever wants to come after me, let him deny himself, and take up his cross, and follow me."},{"v":35,"t":"For whoever wants to save his life will lose it; and whoever will lose his life for my sake and the sake of the Good News will save it."},{"v":36,"t":"For what does it profit a man to gain the whole world and forfeit his life?"},{"v":37,"t":"For what will a man give in exchange for his life?"},{"v":38,"t":"For whoever will be ashamed of me and of my words in this adulterous and sinful generation, the Son of Man also will be ashamed of him when he comes in his Father’s glory with the holy angels.”"}],"hr":[{"v":1,"t":"Onih se dana opet skupio silan svijet. Budući da nisu imali što jesti, dozva Isus učenike pa im reče:"},{"v":2,"t":"“Žao mi je naroda jer su već tri dana uza me i nemaju što jesti."},{"v":3,"t":"Ako ih otpravim gladne njihovim kućama, klonut će putom. A neki su od njih došli iz daleka.”"},{"v":4,"t":"Učenici mu odgovore: “Otkuda bi ih tko ovdje u pustinji mogao nahraniti kruhom?”"},{"v":5,"t":"On ih zapita: “Koliko kruhova imate?” Oni odgovore: “Sedam.”"},{"v":6,"t":"Nato zapovjedi mnoštvu da posjeda po zemlji. I uze sedam kruhova, zahvali, razlomi i davaše svojim učenicima da posluže. I poslužiše mnoštvu."},{"v":7,"t":"A imali su i malo ribica. Blagoslovi i njih te reče da i to posluže."},{"v":8,"t":"I jeli su i nasitili se. A od preteklih ulomaka odniješe sedam košara."},{"v":9,"t":"Bilo ih je oko četiri tisuće. Tada ih otpusti,"},{"v":10,"t":"a sam sa svojim učenicima odmah uđe u lađu i ode u kraj dalmanutski."},{"v":11,"t":"Tada istupiše farizeji i počeše raspravljati s njime. Iskušavajući ga, zatraže od njega znak s neba."},{"v":12,"t":"On uzdahnu iz sve duše i reče: “Zašto ovaj naraštaj traži znak? Zaista, kažem vam, ovome se naraštaju neće dati znak.”"},{"v":13,"t":"Tada ih ostavi, ponovno uđe u lađu pa otiđe prijeko."},{"v":14,"t":"A zaboraviše ponijeti kruha; imali su samo jedan kruh sa sobom na lađi."},{"v":15,"t":"Nato ih Isus opomenu: “Pazite, čuvajte se kvasca farizejskog i kvasca Herodova!”"},{"v":16,"t":"Oni, zamišljeni, među sobom govorahu: “Kruha nemamo.”"},{"v":17,"t":"Zamijetio to Isus pa im reče: “Zašto ste zamišljeni što kruha nemate? Zar još ne shvaćate i ne razumijete? Zar vam je srce stvrdnuto?"},{"v":18,"t":"Oči imate, a ne vidite; uši imate, a ne čujete? Zar se ne sjećate?"},{"v":19,"t":"Kad sam ono razlomio pet kruhova na pet tisuća, koliko punih košara ulomaka odnijeste?” Kažu mu: “Dvanaest.”"},{"v":20,"t":"“A kada razlomih sedam na četiri tisuće, koliko punih košara ulomaka odnijeste?” Odgovore: “Sedam.”"},{"v":21,"t":"A on će njima: “I još ne razumijete?”"},{"v":22,"t":"Dođu u Betsaidu, dovedu mu slijepca pa ga zamole da ga se dotakne."},{"v":23,"t":"On uhvati slijepca za ruku, izvede ga iz sela, pljunu mu u oči, stavi na nj ruke i zapita ga: “Vidiš li što?”"},{"v":24,"t":"Slijepac upilji pogled i reče: “Opažam ljude; vidim nešto kao drveće ... hodaju.”"},{"v":25,"t":"Tada mu Isus opet stavi ruke na oči i slijepac progleda i ozdravi te je mogao sve jasno na daleko vidjeti."},{"v":26,"t":"Tada ga posla kući i reče mu: “Ne ulazi u selo.”"},{"v":27,"t":"I krenu Isus i njegovi učenici u sela Cezareje Filipove. Putem on upita učenike: “Što govore ljudi, tko sam ja?”"},{"v":28,"t":"Oni mu rekoše: “Da si Ivan Krstitelj, drugi da si Ilija, treći opet da si neki od proroka.”"},{"v":29,"t":"On njih upita: “A vi, što vi kažete, tko sam ja?” Petar prihvati i reče: “Ti si Pomazanik - Krist!”"},{"v":30,"t":"I zaprijeti im da nikomu ne kazuju o njemu."},{"v":31,"t":"I poče ih poučavati kako Sin Čovječji treba da mnogo pretrpi, da ga starješine, glavari svećenički i pismoznanci odbace, da bude ubijen i nakon tri dana da ustane."},{"v":32,"t":"Otvoreno im to govoraše. Petar ga uze u stranu i poče odvraćati."},{"v":33,"t":"A on se okrenu, pogleda svoje učenike pa zaprijeti Petru: “Nosi se od mene, sotono, jer ti nije na pameti što je Božje, nego što je ljudsko!”"},{"v":34,"t":"Tada dozva narod i učenike pa im reče: “Hoće li tko za mnom, neka se odrekne samoga sebe, neka uzme svoj križ i neka ide za mnom."},{"v":35,"t":"Tko hoće život svoj spasiti, izgubit će ga; a tko izgubi život svoj poradi mene i evanđelja, spasit će ga."},{"v":36,"t":"Ta što koristi čovjeku steći sav svijet, a životu svojemu nauditi?"},{"v":37,"t":"Ta što da čovjek dadne u zamjenu za život svoj?"},{"v":38,"t":"Doista, tko se zastidi mene i mojih riječi u ovom preljubničkom i grešničkom naraštaju - njega će se stidjeti i Sin Čovječji kada dođe u slavi Oca svoga zajedno sa svetim anđelima.”"}]},"9":{"fa":[{"v":1,"t":"و بدیشان گفت: «هرآینه به شما می‌گویم بعضی از ایستادگان در اینجا می‌باشند که تاملکوت خدا را که به قوت می‌آید نبینند، ذائقه موت را نخواهند چشید.»"},{"v":2,"t":"و بعد از شش روز، عیسی پطرس و یعقوب و یوحنا را برداشته، ایشان را تنها بر فراز کوهی به خلوت برد و هیاتش در نظر ایشان متغیر گشت."},{"v":3,"t":"و لباس او درخشان و چون برف بغایت سفید گردید، چنانکه هیچ گازری بر روی زمین نمی تواند چنان سفید نماید."},{"v":4,"t":"و الیاس با موسی بر ایشان ظاهر شده، با عیسی گفتگو می‌کردند."},{"v":5,"t":"پس پطرس ملتفت شده، به عیسی گفت: «ای استاد، بودن ما در اینجا نیکو است! پس سه سایبان می‌سازیم، یکی برای تو و دیگری برای موسی و سومی برای الیاس!»"},{"v":6,"t":"از آنرو که نمی دانست چه بگوید، چونکه هراسان بودند."},{"v":7,"t":"ناگاه ابری بر ایشان سایه انداخت و آوازی از ابردر‌رسید که «این است پسر حبیب من، از اوبشنوید.»"},{"v":8,"t":"در ساعت گرداگرد خود نگریسته، جزعیسی تنها با خود هیچ‌کس را ندیدند."},{"v":9,"t":"و چون از کوه به زیر می‌آمدند، ایشان راقدغن فرمود که تا پسر انسان از مردگان برنخیزد، از آنچه دیده‌اند کسی را خبر ندهند."},{"v":10,"t":"و این سخن را در خاطر خود نگاه داشته، از یکدیگرسوال می‌کردند که برخاستن از مردگان چه باشد."},{"v":11,"t":"پس از او استفسار کرده، گفتند: «چرا کاتبان می‌گویند که الیاس باید اول بیاید؟»"},{"v":12,"t":"او درجواب ایشان گفت که «الیاس البته اول می‌آید وهمه‌چیز را اصلاح می‌نماید و چگونه درباره پسرانسان مکتوب است که می‌باید زحمت بسیارکشد و حقیر شمرده شود."},{"v":13,"t":"لیکن به شمامی گویم که الیاس هم آمد و با وی آنچه خواستندکردند، چنانچه در حق وی نوشته شده است.»"},{"v":14,"t":"پس چون نزد شاگردان خود رسید، جمعی کثیر گرد ایشان دید و بعضی از کاتبان را که باایشان مباحثه می‌کردند."},{"v":15,"t":"در ساعت، تمامی خلق چون او را بدیدند در حیرت افتادند و دوان دوان آمده، او را سلام دادند."},{"v":16,"t":"آنگاه از کاتبان پرسید که «با اینها چه مباحثه دارید؟»"},{"v":17,"t":"یکی ازآن میان در جواب گفت: «ای استاد، پسر خود رانزد تو آوردم که روحی گنگ دارد،"},{"v":18,"t":"و هر جا که او را بگیرد می‌اندازدش، چنانچه کف برآورده، دندانهایم بهم می‌ساید و خشک می‌گردد. پس شاگردان تو را گفتم که او را بیرون کنند، نتوانستند.»"},{"v":19,"t":"او ایشان را جواب داده، گفت: «ای فرقه بی‌ایمان تا کی با شما باشم و تا چه حدمتحمل شما شوم! او را نزد من آورید.»"},{"v":20,"t":"پس اورا نزد وی آوردند. چون او را دید، فور آن روح او را مصروع کرد تا بر زمین افتاده، کف برآورد وغلطان شد."},{"v":21,"t":"پس از پدر وی پرسید: «چند وقت است که او را این حالت است؟» گفت: «ازطفولیت."},{"v":22,"t":"و بارها او را در آتش و در آب انداخت تا او را هلاک کند. حال اگر می‌توانی بر ماترحم کرده، ما را مدد فرما.»"},{"v":23,"t":"عیسی وی راگفت: «اگر می‌توانی‌ایمان آری، مومن را همه‌چیزممکن است.»"},{"v":24,"t":"در ساعت پدر طفل فریادبرآورده، گریه‌کنان گفت: «ایمان می‌آورم‌ای خداوند، بی‌ایمانی مرا امداد فرما.»"},{"v":25,"t":"چون عیسی دید که گروهی گرد او به شتاب می‌آیند، روح پلید را نهیب داده، به وی فرمود: «ای روح گنگ و کر من تو را حکم می‌کنم از او در آی ودیگر داخل او مشو!»"},{"v":26,"t":"پس صیحه زده و او رابشدت مصروع نموده، بیرون آمد و مانند مرده گشت، چنانکه بسیاری گفتند که فوت شد."},{"v":27,"t":"اما عیسی دستش را گرفته، برخیزانیدش که برپاایستاد."},{"v":28,"t":"و چون به خانه در‌آمد، شاگردانش درخلوت از او پرسیدند: «چرا ما نتوانستیم او رابیرون کنیم؟»"},{"v":29,"t":"ایشان را گفت: «این جنس به هیچ وجه بیرون نمی رود جز به دعا.»"},{"v":30,"t":"و از آنجا روانه شده، در جلیل می‌گشتند ونمی خواست کسی او را بشناسد،"},{"v":31,"t":"زیرا که شاگردان خود را اعلام فرموده، می‌گفت: «پسرانسان به‌دست مردم تسلیم می‌شود و او راخواهند کشت و بعد از مقتول شدن، روز سوم خواهد برخاست.»"},{"v":32,"t":"اما این سخن را درک نکردند و ترسیدند که از او بپرسند."},{"v":33,"t":"و وارد کفرناحوم شده، چون به خانه درآمد، از ایشان پرسید که «در بین راه با یک دیگرچه مباحثه می‌کردید؟»"},{"v":34,"t":"اما ایشان خاموش ماندند، از آنجا که در راه با یکدیگر گفتگومی کردند در اینکه کیست بزرگتر."},{"v":35,"t":"پس نشسته، آن دوازده را طلبیده، بدیشان گفت: «هر‌که می‌خواهد مقدم باشد موخر و غلام همه بود."},{"v":36,"t":"پس طفلی را برداشته، در میان ایشان بر پا نمودو او را در آغوش کشیده، به ایشان گفت:"},{"v":37,"t":"«هرکه یکی از این کودکان را به اسم من قبول کند، مراقبول کرده است و هر‌که مرا پذیرفت نه مرا بلکه فرستنده مرا پذیرفته باشد."},{"v":38,"t":"آنگاه یوحنا ملتفت شده، بدو گفت: «ای استاد، شخصی را دیدیم که به نام تو دیوها بیرون می‌کرد و متابعت ما نمی نمود؛ و چون متابعت مانمی کرد، او را ممانعت نمودیم.»"},{"v":39,"t":"عیسی گفت: «او را منع مکنید، زیرا هیچ‌کس نیست که معجزه‌ای به نام من بنماید و بتواند به زودی درحق من بد گوید."},{"v":40,"t":"زیرا هر‌که ضد ما نیست باماست."},{"v":41,"t":"و هر‌که شما را از این‌رو که از آن مسیح هستید، کاسه‌ای آب به اسم من بنوشاند، هرآینه به شما می‌گویم اجر خود را ضایع نخواهد کرد."},{"v":42,"t":"و هر‌که یکی از این کودکان را که به من ایمان آورند، لغزش دهد، او را بهتر است که سنگ آسیایی بر گردنش آویخته، در دریا افکنده شود."},{"v":43,"t":"پس هرگاه دستت تو را بلغزاند، آن را ببرزیرا تو را بهتر است که شل داخل حیات شوی، ازاینکه با دو دست وارد جهنم گردی، در آتشی که خاموشی نپذیرد؛"},{"v":44,"t":"جایی که کرم ایشان نمیرد وآتش، خاموشی نپذیرد."},{"v":45,"t":"و هرگاه پایت تو رابلغزاند، قطعش کن زیرا تو را مفیدتر است که لنگ داخل حیات شوی از آنکه با دو پا به جهنم افکنده شوی، در آتشی که خاموشی نپذیرد؛"},{"v":46,"t":"آنجایی که کرم ایشان نمیرد و آتش، خاموش نشود."},{"v":47,"t":"و هر گاه چشم تو تو را لغزش دهد، قلعش کن زیرا تو را بهتر است که با یک چشم داخل ملکوت خدا شوی، از آنکه با دو چشم درآتش جهنم انداخته شوی،"},{"v":48,"t":"جایی که کرم ایشان نمیرد و آتش خاموشی نیابد."},{"v":49,"t":"زیرا هرکس به آتش، نمکین خواهد شد و هر قربانی به نمک، نمکین می‌گردد."},{"v":50,"t":"نمک نیکو است، لیکن هر گاه نمک فاسد گردد به چه چیز آن را اصلاح می‌کنید؟ پس در خود نمک بدارید و با یکدیگرصلح نمایید.»"}],"en":[{"v":1,"t":"He said to them, “Most certainly I tell you, there are some standing here who will in no way taste death until they see God’s Kingdom come with power.”"},{"v":2,"t":"After six days Jesus took with him Peter, James, and John, and brought them up onto a high mountain privately by themselves, and he was changed into another form in front of them."},{"v":3,"t":"His clothing became glistening, exceedingly white, like snow, such as no launderer on earth can whiten them."},{"v":4,"t":"Elijah and Moses appeared to them, and they were talking with Jesus."},{"v":5,"t":"Peter answered Jesus, “Rabbi, it is good for us to be here. Let’s make three tents: one for you, one for Moses, and one for Elijah.”"},{"v":6,"t":"For he didn’t know what to say, for they were very afraid."},{"v":7,"t":"A cloud came, overshadowing them, and a voice came out of the cloud, “This is my beloved Son. Listen to him.”"},{"v":8,"t":"Suddenly looking around, they saw no one with them any more, except Jesus only."},{"v":9,"t":"As they were coming down from the mountain, he commanded them that they should tell no one what things they had seen, until after the Son of Man had risen from the dead."},{"v":10,"t":"They kept this saying to themselves, questioning what the “rising from the dead” meant."},{"v":11,"t":"They asked him, saying, “Why do the scribes say that Elijah must come first?”"},{"v":12,"t":"He said to them, “Elijah indeed comes first, and restores all things. How is it written about the Son of Man, that he should suffer many things and be despised?"},{"v":13,"t":"But I tell you that Elijah has come, and they have also done to him whatever they wanted to, even as it is written about him.”"},{"v":14,"t":"Coming to the disciples, he saw a great multitude around them, and scribes questioning them."},{"v":15,"t":"Immediately all the multitude, when they saw him, were greatly amazed, and running to him, greeted him."},{"v":16,"t":"He asked the scribes, “What are you asking them?”"},{"v":17,"t":"One of the multitude answered, “Teacher, I brought to you my son, who has a mute spirit;"},{"v":18,"t":"and wherever it seizes him, it throws him down; and he foams at the mouth, grinds his teeth, and becomes rigid. I asked your disciples to cast it out, and they weren’t able.”"},{"v":19,"t":"He answered him, “Unbelieving generation, how long shall I be with you? How long shall I bear with you? Bring him to me.”"},{"v":20,"t":"They brought him to him, and when he saw him, immediately the spirit convulsed him and he fell on the ground, wallowing and foaming at the mouth."},{"v":21,"t":"He asked his father, “How long has it been since this has been happening to him?” He said, “From childhood."},{"v":22,"t":"Often it has cast him both into the fire and into the water to destroy him. But if you can do anything, have compassion on us and help us.”"},{"v":23,"t":"Jesus said to him, “If you can believe, all things are possible to him who believes.”"},{"v":24,"t":"Immediately the father of the child cried out with tears, “I believe. Help my unbelief!”"},{"v":25,"t":"When Jesus saw that a multitude came running together, he rebuked the unclean spirit, saying to him, “You mute and deaf spirit, I command you, come out of him, and never enter him again!”"},{"v":26,"t":"After crying out and convulsing him greatly, it came out of him. The boy became like one dead, so much that most of them said, “He is dead.”"},{"v":27,"t":"But Jesus took him by the hand and raised him up; and he arose."},{"v":28,"t":"When he had come into the house, his disciples asked him privately, “Why couldn’t we cast it out?”"},{"v":29,"t":"He said to them, “This kind can come out by nothing but by prayer and fasting.”"},{"v":30,"t":"They went out from there and passed through Galilee. He didn’t want anyone to know it,"},{"v":31,"t":"for he was teaching his disciples, and said to them, “The Son of Man is being handed over to the hands of men, and they will kill him; and when he is killed, on the third day he will rise again.”"},{"v":32,"t":"But they didn’t understand the saying, and were afraid to ask him."},{"v":33,"t":"He came to Capernaum, and when he was in the house he asked them, “What were you arguing among yourselves on the way?”"},{"v":34,"t":"But they were silent, for they had disputed with one another on the way about who was the greatest."},{"v":35,"t":"He sat down and called the twelve; and he said to them, “If any man wants to be first, he shall be last of all, and servant of all.”"},{"v":36,"t":"He took a little child and set him in the middle of them. Taking him in his arms, he said to them,"},{"v":37,"t":"“Whoever receives one such little child in my name receives me; and whoever receives me, doesn’t receive me, but him who sent me.”"},{"v":38,"t":"John said to him, “Teacher, we saw someone who doesn’t follow us casting out demons in your name; and we forbade him, because he doesn’t follow us.”"},{"v":39,"t":"But Jesus said, “Don’t forbid him, for there is no one who will do a mighty work in my name and be able quickly to speak evil of me."},{"v":40,"t":"For whoever is not against us is on our side."},{"v":41,"t":"For whoever will give you a cup of water to drink in my name because you are Christ’s, most certainly I tell you, he will in no way lose his reward."},{"v":42,"t":"“Whoever will cause one of these little ones who believe in me to stumble, it would be better for him if he were thrown into the sea with a millstone hung around his neck."},{"v":43,"t":"If your hand causes you to stumble, cut it off. It is better for you to enter into life maimed, rather than having your two hands to go into Gehenna, into the unquenchable fire,"},{"v":44,"t":"‘where their worm doesn’t die, and the fire is not quenched.’"},{"v":45,"t":"If your foot causes you to stumble, cut it off. It is better for you to enter into life lame, rather than having your two feet to be cast into Gehenna, into the fire that will never be quenched—"},{"v":46,"t":"‘where their worm doesn’t die, and the fire is not quenched.’"},{"v":47,"t":"If your eye causes you to stumble, throw it out. It is better for you to enter into God’s Kingdom with one eye, rather than having two eyes to be cast into the Gehenna of fire,"},{"v":48,"t":"‘where their worm doesn’t die, and the fire is not quenched.’"},{"v":49,"t":"For everyone will be salted with fire, and every sacrifice will be seasoned with salt."},{"v":50,"t":"Salt is good, but if the salt has lost its saltiness, with what will you season it? Have salt in yourselves, and be at peace with one another.”"}],"hr":[{"v":1,"t":"Još im govoraše: “Zaista, kažem vam, neki od ovdje nazočnih neće okusiti smrti dok ne vide da je kraljevstvo Božje došlo u sili.”"},{"v":2,"t":"Nakon šest dana uze Isus sa sobom Petra, Jakova i Ivana i povede ih na goru visoku, u osamu, same, i preobrazi se pred njima."},{"v":3,"t":"I haljine mu postadoše sjajne, bijele veoma - nijedan ih bjelilac na zemlji ne bi mogao tako izbijeliti."},{"v":4,"t":"I ukaza im se Ilija s Mojsijem te razgovarahu s Isusom."},{"v":5,"t":"A Petar prihvati i reče Isusu: “Učitelju, dobro nam je ovdje biti! Načinimo tri sjenice: tebi jednu, Mojsiju jednu i Iliji jednu.”"},{"v":6,"t":"Doista nije znao što da kaže jer bijahu prestrašeni."},{"v":7,"t":"I pojavi se oblak i zasjeni ih, a iz oblaka se začu glas: “Ovo je Sin moj, Ljubljeni! Slušajte ga!”"},{"v":8,"t":"I odjednom, obazrevši se uokolo, nikoga uza se ne vidješe doli Isusa sama."},{"v":9,"t":"Dok su silazili s gore, naloži im da nikomu ne pripovijedaju što su vidjeli dok Sin Čovječji od mrtvih ne ustane."},{"v":10,"t":"Oni održaše tu riječ, ali se među sobom pitahu što znači to njegovo “od mrtvih ustati”"},{"v":11,"t":"pa ga upitaju: “Zašto pismoznanci govore da prije treba da dođe Ilija?”"},{"v":12,"t":"A on im reče: “Ilija će, doduše, prije doći i sve obnoviti. Pa kako ipak piše o Sinu Čovječjem da će mnogo pretrpjeti i biti prezren?"},{"v":13,"t":"Ali, velim vam: Ilija je već došao i oni učiniše s njim što im se prohtjelo, kao što piše o njemu.”"},{"v":14,"t":"Kada dođoše k učenicima, ugledaše oko njih silan svijet i pismoznance kako raspravljaju s njima."},{"v":15,"t":"Čim ga sve ono mnoštvo ugleda, iznenađeno brže pohrli pozdraviti ga."},{"v":16,"t":"A on ih upita: “Što to raspravljaste s njima?”"},{"v":17,"t":"Odvrati netko iz mnoštva: “Učitelju, dovedoh k tebi svoga sina koji ima nijemoga duha."},{"v":18,"t":"Gdje ga god zgrabi, obara ga, a on pjeni, škripi zubima i koči se. Rekoh tvojim učenicima da ga izagnaju, ali ne mogoše.”"},{"v":19,"t":"On im odvrati: “O rode nevjerni! Dokle mi je biti s vama? Dokle li vas podnositi? Dovedite ga k meni!”"},{"v":20,"t":"I dovedoše ga k njemu. Čim zloduh ugleda Isusa, potrese dječakom i on se, oboren na zemlju, stane valjati i pjeniti."},{"v":21,"t":"Isus upita njegova oca: “Koliko je vremena kako mu se to događa?” On reče: “Od djetinjstva!"},{"v":22,"t":"A često ga znade baciti i u vatru i u vodu da ga upropasti. Nego, ako što možeš, pomozi nam, imaj samilosti s nama!”"},{"v":23,"t":"Nato mu Isus reče: “Što? Ako možeš? Sve je moguće onomu koji vjeruje!”"},{"v":24,"t":"Dječakov otac brže povika: “Vjerujem! Pomozi mojoj nevjeri!”"},{"v":25,"t":"Vidjevši da svijet odasvud grne, Isus zaprijeti nečistomu duhu: “Nijemi i gluhi duše, ja ti zapovijedam, iziđi iz njega i da nisi više u nj ušao!”"},{"v":26,"t":"Zloduh nato zaviče, žestoko strese dječaka te iziđe, a on osta kao mrtav te su mnogi govorili da je umro."},{"v":27,"t":"No Isus ga dohvati za ruku, podiže ga i on ustade."},{"v":28,"t":"Kad Isus uđe u kuću, upitaše ga učenici nasamo: “Kako to da ga mi ne mogosmo izagnati?”"},{"v":29,"t":"Odgovori im: “Ovaj se rod ničim drugim ne može izagnati osim molitvom i postom.”"},{"v":30,"t":"Otišavši odande, prolažahu kroz Galileju. On ne htjede da to itko sazna."},{"v":31,"t":"Jer poučavaše svoje učenike. Govoraše im: “Sin Čovječji predaje se u ruke ljudima. Ubit će ga, ali će on, ubijen, nakon tri dana ustati.”"},{"v":32,"t":"No oni ne razumješe te besjede, a bojahu ga se pitati."},{"v":33,"t":"I dođoše u Kafarnaum. I već u kući upita ih: “Što ste putem raspravljali?”"},{"v":34,"t":"A oni umukoše jer putem među sobom razgovarahu o tome tko je najveći."},{"v":35,"t":"On sjede i dozove dvanaestoricu te im reče: “Ako tko želi biti prvi, neka bude od svih posljednji i svima poslužitelj!”"},{"v":36,"t":"I uzme dijete, postavi ga posred njih, zagrli ga i reče im:"},{"v":37,"t":"“Tko god jedno ovakvo dijete primi u moje ime, mene prima. A tko mene prima, ne prima mene, nego onoga koji mene posla.”"},{"v":38,"t":"Reče mu Ivan: “Učitelju, vidjesmo jednoga kako u tvoje ime izgoni zloduhe. Mi smo mu branili jer ne ide s nama.”"},{"v":39,"t":"A Isus reče: “Ne branite mu! Jer nitko ne može učiniti nešto silno u moje ime pa me ubrzo zatim pogrditi."},{"v":40,"t":"Tko nije protiv nas, za nas je.”"},{"v":41,"t":"“Uistinu, tko vas napoji čašom vode u ime toga što ste Kristovi, zaista, kažem vam, neće mu propasti plaća.”"},{"v":42,"t":"“Onomu naprotiv tko bi sablaznio jednoga od ovih najmanjih što vjeruju, daleko bi bolje bilo da s mlinskim kamenom o vratu bude bačen u more.”"},{"v":43,"t":"“Pa ako te ruka sablažnjava, odsijeci je. Bolje ti je sakatu ući u život, nego s obje ruke otići u pakao, u oganj neugasivi."},{"v":44,"t":"#"},{"v":45,"t":"I ako te noga sablažnjava, odsijeci je. Bolje ti je hromu ući u život, nego s obje noge bit bačen u pakao."},{"v":46,"t":"#"},{"v":47,"t":"I ako te oko sablažnjava, iskopaj ga. Bolje ti je jednooku ući u kraljevstvo Božje, nego s oba oka biti bačen u pakao,"},{"v":48,"t":"gdje crv njihov ne gine niti se oganj gasi."},{"v":49,"t":"Uistinu, ognjem će svaki od njih biti posoljen."},{"v":50,"t":"Dobra je sol. Ali ako sol postane neslana, čime ćete nju začiniti? Imajte sol u sebi, a mir među sobom!”"}]},"10":{"fa":[{"v":1,"t":"و از آنجا برخاسته، از آن طرف اردن به نواحی یهودیه آمد. و گروهی باز نزدوی جمع شدند و او برحسب عادت خود، بازبدیشان تعلیم می‌داد."},{"v":2,"t":"آنگاه فریسیان پیش آمده، از روی امتحان ازاو سوال نمودند که «آیا مرد را طلاق دادن زن خویش جایز است.»"},{"v":3,"t":"در جواب ایشان گفت: «موسی شما را چه فرموده است؟»"},{"v":4,"t":"گفتند: «موسی اجازت داد که طلاق نامه بنویسند و رهاکنند.»"},{"v":5,"t":"عیسی در جواب ایشان گفت: «به‌سبب سنگدلی شما این حکم را برای شما نوشت."},{"v":6,"t":"لیکن از ابتدای خلقت، خدا ایشان را مرد و زن آفرید."},{"v":7,"t":"از آن جهت باید مرد پدر و مادر خود را ترک کرده، با زن خویش بپیوندد،"},{"v":8,"t":"و این دو یک تن خواهند بود چنانکه از آن پس دو نیستند بلکه یک جسد."},{"v":9,"t":"پس آنچه خدا پیوست، انسان آن راجدا نکند.»"},{"v":10,"t":"و در خانه باز شاگردانش از این مقدمه ازوی سوال نمودند."},{"v":11,"t":"بدیشان گفت: «هر‌که زن خود را طلاق دهد و دیگری را نکاح کند، بر‌حق وی زنا کرده باشد."},{"v":12,"t":"و اگر زن از شوهر خود جداشود و منکوحه دیگری گردد، مرتکب زنا شود.»"},{"v":13,"t":"و بچه های کوچک را نزد او آوردند تاایشان را لمس نماید؛ اما شاگردان آورندگان رامنع کردند."},{"v":14,"t":"چون عیسی این را بدید، خشم نموده، بدیشان گفت: «بگذارید که بچه های کوچک نزد من آیند و ایشان را مانع نشوید، زیراملکوت خدا از امثال اینها است."},{"v":15,"t":"هرآینه به شما می‌گویم هر‌که ملکوت خدا را مثل بچه کوچک قبول نکند، داخل آن نشود.»"},{"v":16,"t":"پس ایشان را در آغوش کشید و دست بر ایشان نهاده، برکت داد."},{"v":17,"t":"چون به راه می‌رفت، شخصی دوان دوان آمده، پیش او زانو زده، سوال نمود که «ای استادنیکو چه کنم تا وارث حیات جاودانی شوم؟"},{"v":18,"t":"عیسی بدو گفت: «چرا مرا نیکو گفتی و حال آنکه کسی نیکو نیست جز خدا فقط؟"},{"v":19,"t":"احکام را می دانی، زنا مکن، قتل مکن، دزدی مکن، شهادت دروغ مده، دغابازی مکن، پدر و مادر خود راحرمت دار.»"},{"v":20,"t":"او در جواب وی گفت: «ای استاد، این همه را از طفولیت نگاه داشتم.»"},{"v":21,"t":"عیسی به وی نگریسته، او را محبت نمود وگفت: «تو را یک چیز ناقص است: برو و آنچه داری بفروش و به فقرا بده که در آسمان گنجی خواهی یافت و بیا صلیب را برداشته، مرا پیروی کن.»"},{"v":22,"t":"لیکن او از این سخن ترش رو و محزون گشته، روانه گردید زیرا اموال بسیار داشت."},{"v":23,"t":"آنگاه عیسی گرداگرد خود نگریسته، به شاگردان خود گفت: «چه دشوار است که توانگران داخل ملکوت خدا شوند.»"},{"v":24,"t":"چون شاگردانش از سخنان او در حیرت افتادند، عیسی باز توجه نموده، بدیشان گفت: «ای فرزندان، چه دشوار است دخول آنانی که به مال و اموال توکل دارند در ملکوت خدا!"},{"v":25,"t":"سهل تر است که شتر به سوراخ سوزن درآید از اینکه شخص دولتمند به ملکوت خدا داخل شود!»"},{"v":26,"t":"ایشان بغایت متحیرگشته، با یکدیگر می‌گفتند: «پس که می‌تواندنجات یابد؟»"},{"v":27,"t":"عیسی به ایشان نظر کرده، گفت: «نزد انسان محال است لیکن نزد خدا نیست زیراکه همه‌چیز نزد خدا ممکن است.»"},{"v":28,"t":"پطرس بدوگفتن گرفت که «اینک ما همه‌چیز را ترک کرده، تورا پیروی کرده‌ایم.»"},{"v":29,"t":"عیسی جواب فرمود: «هرآینه به شما می‌گویم کسی نیست که خانه یابرادران یا خواهران یا پدر یا مادر یا زن یا اولاد یااملاک را بجهت من و انجیل ترک کند،"},{"v":30,"t":"جزاینکه الحال در این زمان صد چندان یابد ازخانه‌ها و برادران و خواهران و مادران و فرزندان و املاک با زحمات، و در عالم آینده حیات جاودانی را."},{"v":31,"t":"اما بسا اولین که آخرین می‌گردندو آخرین اولین.»"},{"v":32,"t":"و چون در راه به سوی اورشلیم می‌رفتند وعیسی در جلو ایشان می‌خرامید، در حیرت افتادند و چون از عقب او می‌رفتند، ترس بر ایشان مستولی شد. آنگاه آن دوازده را باز به کنارکشیده، شروع کرد به اطلاع دادن به ایشان از آنچه بر وی وارد می‌شد،"},{"v":33,"t":"که «اینک به اورشلیم می‌رویم و پسر انسان به‌دست روسای کهنه وکاتبان تسلیم شود و بر وی فتوای قتل دهند و اورا به امتها سپارند،"},{"v":34,"t":"و بر وی سخریه نموده، تازیانه‌اش زنند و آب دهان بر وی افکنده، او راخواهند کشت و روز سوم خواهد برخاست.»"},{"v":35,"t":"آنگاه یعقوب و یوحنا دو پسر زبدی نزدوی آمده، گفتند: «ای استاد، می‌خواهیم آنچه ازتو سوال کنیم برای ما بکنی.»"},{"v":36,"t":"ایشان را گفت: «چه می‌خواهید برای شما بکنم؟»"},{"v":37,"t":"گفتند: «به ما عطا فرما که یکی به طرف راست و دیگری برچپ تو در جلال تو بنشینیم.»"},{"v":38,"t":"عیسی ایشان راگفت: «نمی فهمید آنچه می‌خواهید. آیا می‌توانیدآن پیاله‌ای را که من می‌نوشم، بنوشید و تعمیدی را که من می‌پذیرم، بپذیرید؟»"},{"v":39,"t":"وی را گفتند: «می‌توانیم.» عیسی بدیشان گفت: «پیاله‌ای را که من می‌نوشم خواهید آشامید و تعمیدی را که من می‌پذیرم خواهید پذیرفت."},{"v":40,"t":"لیکن نشستن به‌دست راست و چپ من از آن من نیست که بدهم جز آنانی را که از بهر ایشان مهیا شده است.»"},{"v":41,"t":"وآن ده نفر چون شنیدند بر یعقوب و یوحنا خشم گرفتند."},{"v":42,"t":"عیسی ایشان را خوانده، به ایشان گفت: «می‌دانید آنانی که حکام امتها شمرده می‌شوند برایشان ریاست می‌کنند و بزرگانشان بر ایشان مسلطند."},{"v":43,"t":"لیکن در میان شما چنین نخواهد بود، بلکه هر‌که خواهد در میان شما بزرگ شود، خادم شما باشد."},{"v":44,"t":"و هر‌که خواهد مقدم بر شما شود، غلام همه باشد."},{"v":45,"t":"زیرا که پسر انسان نیز نیامده تامخدوم شود بلکه تا خدمت کند و تا جان خود رافدای بسیاری کند.»"},{"v":46,"t":"و وارد اریحا شدند. و وقتی که او باشاگردان خود و جمعی کثیر از اریحا بیرون می‌رفت، بارتیمائوس کور، پسر تیماوس بر کناره راه نشسته، گدایی می‌کرد."},{"v":47,"t":"چون شنید که عیسی ناصری است، فریاد کردن گرفت و گفت: «ای عیسی ابن داود بر من ترحم کن.»"},{"v":48,"t":"و چندان‌که بسیاری او را نهیب می‌دادند که خاموش شود، زیادتر فریاد برمی آورد که پسر داودا بر من ترحم فرما."},{"v":49,"t":"پس عیسی ایستاده، فرمود تا او را بخوانند. آنگاه آن کور را خوانده، بدو گفتند: «خاطر جمع دار برخیز که تو را می‌خواند.»"},{"v":50,"t":"درساعت ردای خود را دور انداخته، بر پا جست ونزد عیسی آمد."},{"v":51,"t":"عیسی به وی التفات نموده، گفت: «چه می‌خواهی از بهر تو نمایم؟» کور بدوگفت: «یا سیدی آنکه بینایی یابم.»"},{"v":52,"t":"عیسی بدوگفت: «برو که ایمانت تو را شفا داده است.» درساعت بینا گشته، از عقب عیسی در راه روانه شد."}],"en":[{"v":1,"t":"He arose from there and came into the borders of Judea and beyond the Jordan. Multitudes came together to him again. As he usually did, he was again teaching them."},{"v":2,"t":"Pharisees came to him testing him, and asked him, “Is it lawful for a man to divorce his wife?”"},{"v":3,"t":"He answered, “What did Moses command you?”"},{"v":4,"t":"They said, “Moses allowed a certificate of divorce to be written, and to divorce her.”"},{"v":5,"t":"But Jesus said to them, “For your hardness of heart, he wrote you this commandment."},{"v":6,"t":"But from the beginning of the creation, God made them male and female."},{"v":7,"t":"For this cause a man will leave his father and mother, and will join to his wife,"},{"v":8,"t":"and the two will become one flesh, so that they are no longer two, but one flesh."},{"v":9,"t":"What therefore God has joined together, let no man separate.”"},{"v":10,"t":"In the house, his disciples asked him again about the same matter."},{"v":11,"t":"He said to them, “Whoever divorces his wife and marries another commits adultery against her."},{"v":12,"t":"If a woman herself divorces her husband and marries another, she commits adultery.”"},{"v":13,"t":"They were bringing to him little children, that he should touch them, but the disciples rebuked those who were bringing them."},{"v":14,"t":"But when Jesus saw it, he was moved with indignation and said to them, “Allow the little children to come to me! Don’t forbid them, for God’s Kingdom belongs to such as these."},{"v":15,"t":"Most certainly I tell you, whoever will not receive God’s Kingdom like a little child, he will in no way enter into it.”"},{"v":16,"t":"He took them in his arms and blessed them, laying his hands on them."},{"v":17,"t":"As he was going out into the way, one ran to him, knelt before him, and asked him, “Good Teacher, what shall I do that I may inherit eternal life?”"},{"v":18,"t":"Jesus said to him, “Why do you call me good? No one is good except one—God."},{"v":19,"t":"You know the commandments: ‘Do not murder,’ ‘Do not commit adultery,’ ‘Do not steal,’ ‘Do not give false testimony,’ ‘Do not defraud,’ ‘Honor your father and mother.’”"},{"v":20,"t":"He said to him, “Teacher, I have observed all these things from my youth.”"},{"v":21,"t":"Jesus looking at him loved him, and said to him, “One thing you lack. Go, sell whatever you have and give to the poor, and you will have treasure in heaven; and come, follow me, taking up the cross.”"},{"v":22,"t":"But his face fell at that saying, and he went away sorrowful, for he was one who had great possessions."},{"v":23,"t":"Jesus looked around and said to his disciples, “How difficult it is for those who have riches to enter into God’s Kingdom!”"},{"v":24,"t":"The disciples were amazed at his words. But Jesus answered again, “Children, how hard it is for those who trust in riches to enter into God’s Kingdom!"},{"v":25,"t":"It is easier for a camel to go through a needle’s eye than for a rich man to enter into God’s Kingdom.”"},{"v":26,"t":"They were exceedingly astonished, saying to him, “Then who can be saved?”"},{"v":27,"t":"Jesus, looking at them, said, “With men it is impossible, but not with God, for all things are possible with God.”"},{"v":28,"t":"Peter began to tell him, “Behold, we have left all and have followed you.”"},{"v":29,"t":"Jesus said, “Most certainly I tell you, there is no one who has left house, or brothers, or sisters, or father, or mother, or wife, or children, or land, for my sake, and for the sake of the Good News,"},{"v":30,"t":"but he will receive one hundred times more now in this time: houses, brothers, sisters, mothers, children, and land, with persecutions; and in the age to come eternal life."},{"v":31,"t":"But many who are first will be last, and the last first.”"},{"v":32,"t":"They were on the way, going up to Jerusalem; and Jesus was going in front of them, and they were amazed; and those who followed were afraid. He again took the twelve, and began to tell them the things that were going to happen to him."},{"v":33,"t":"“Behold, we are going up to Jerusalem. The Son of Man will be delivered to the chief priests and the scribes. They will condemn him to death, and will deliver him to the Gentiles."},{"v":34,"t":"They will mock him, spit on him, scourge him, and kill him. On the third day he will rise again.”"},{"v":35,"t":"James and John, the sons of Zebedee, came near to him, saying, “Teacher, we want you to do for us whatever we will ask.”"},{"v":36,"t":"He said to them, “What do you want me to do for you?”"},{"v":37,"t":"They said to him, “Grant to us that we may sit, one at your right hand and one at your left hand, in your glory.”"},{"v":38,"t":"But Jesus said to them, “You don’t know what you are asking. Are you able to drink the cup that I drink, and to be baptized with the baptism that I am baptized with?”"},{"v":39,"t":"They said to him, “We are able.” Jesus said to them, “You shall indeed drink the cup that I drink, and you shall be baptized with the baptism that I am baptized with;"},{"v":40,"t":"but to sit at my right hand and at my left hand is not mine to give, but for whom it has been prepared.”"},{"v":41,"t":"When the ten heard it, they began to be indignant toward James and John."},{"v":42,"t":"Jesus summoned them and said to them, “You know that they who are recognized as rulers over the nations lord it over them, and their great ones exercise authority over them."},{"v":43,"t":"But it shall not be so among you, but whoever wants to become great among you shall be your servant."},{"v":44,"t":"Whoever of you wants to become first among you shall be bondservant of all."},{"v":45,"t":"For the Son of Man also came not to be served but to serve, and to give his life as a ransom for many.”"},{"v":46,"t":"They came to Jericho. As he went out from Jericho with his disciples and a great multitude, the son of Timaeus, Bartimaeus, a blind beggar, was sitting by the road."},{"v":47,"t":"When he heard that it was Jesus the Nazarene, he began to cry out and say, “Jesus, you son of David, have mercy on me!”"},{"v":48,"t":"Many rebuked him, that he should be quiet, but he cried out much more, “You son of David, have mercy on me!”"},{"v":49,"t":"Jesus stood still and said, “Call him.” They called the blind man, saying to him, “Cheer up! Get up. He is calling you!”"},{"v":50,"t":"He, casting away his cloak, sprang up, and came to Jesus."},{"v":51,"t":"Jesus asked him, “What do you want me to do for you?” The blind man said to him, “Rabboni, that I may see again.”"},{"v":52,"t":"Jesus said to him, “Go your way. Your faith has made you well.” Immediately he received his sight and followed Jesus on the way."}],"hr":[{"v":1,"t":"Krenuvši odande, dođe u judejski kraj i na onu stranu Jordana. I opet mnoštvo nagrnu k njemu, a on ih po svojem običaju ponovno poučavaše."},{"v":2,"t":"A pristupe farizeji pa, da ga iskušaju, upitaše: “Je li mužu dopušteno otpustiti ženu?”"},{"v":3,"t":"On im odgovori: “Što vam zapovjedi Mojsije?”"},{"v":4,"t":"Oni rekoše: “Mojsije je dopustio napisati otpusno pismo i - otpustiti.”"},{"v":5,"t":"A Isus će im: “Zbog okorjelosti srca vašega napisa vam on tu zapovijed."},{"v":6,"t":"Od početka stvorenja muško i žensko stvori ih."},{"v":7,"t":"Stoga će čovjek ostaviti oca i majku da prione uza svoju ženu;"},{"v":8,"t":"i dvoje njih bit će jedno tijelo. Tako više nisu dvoje, nego jedno tijelo."},{"v":9,"t":"Što dakle Bog združi, čovjek neka ne rastavlja!”"},{"v":10,"t":"U kući su ga učenici ponovno o tome ispitivali."},{"v":11,"t":"I reče im: “Tko otpusti svoju ženu pa se oženi drugom, čini prema prvoj preljub."},{"v":12,"t":"I ako žena napusti svoga muža pa se uda za drugoga, čini preljub.”"},{"v":13,"t":"Donosili mu dječicu da ih se dotakne, a učenici im branili."},{"v":14,"t":"Opazivši to, Isus se ozlovolji i reče im: “Pustite dječicu neka dolaze k meni; ne priječite im jer takvih je kraljevstvo Božje!"},{"v":15,"t":"Zaista, kažem vam, tko ne primi kraljevstva Božjega kao dijete, ne, u nj neće ući.”"},{"v":16,"t":"Nato ih zagrli pa ih blagoslivljaše polažući na njih ruke."},{"v":17,"t":"I dok je izlazio na put, dotrči netko, klekne preda nj pa ga upita: “Učitelju dobri, što mi je činiti da baštinim život vječni?”"},{"v":18,"t":"Isus mu reče: “Što me zoveš dobrim? Nitko nije dobar doli Bog jedini!"},{"v":19,"t":"Zapovijedi znadeš: Ne ubij! Ne čini preljuba! Ne ukradi! Ne svjedoči lažno! Ne otmi! Poštuj oca svoga i majku!”"},{"v":20,"t":"On mu odgovori: “Učitelju, sve sam to čuvao od svoje mladosti.”"},{"v":21,"t":"Isus ga nato pogleda, zavoli ga i rekne mu: “Jedno ti nedostaje! Idi i što imaš, prodaj i podaj siromasima pa ćeš imati blago na nebu. A onda dođi i idi za mnom.”"},{"v":22,"t":"On se na tu riječ smrkne i ode žalostan jer imaše velik imetak."},{"v":23,"t":"Isus zaokruži pogledom pa će svojim učenicima: “Kako li će teško imućnici u kraljevstvo Božje!”"},{"v":24,"t":"Učenici ostadoše zapanjeni tim njegovim riječima. Zato im Isus ponovi: “Djeco, kako je teško u kraljevstvo Božje!"},{"v":25,"t":"Lakše je devi kroz ušice iglene nego bogatašu u kraljevstvo Božje.”"},{"v":26,"t":"Oni se još većma snebivahu te će jedan drugome: “Pa tko se onda može spasiti?”"},{"v":27,"t":"Isus upre u njih pogled i reče: “Ljudima je nemoguće, ali ne Bogu! Ta Bogu je sve moguće!”"},{"v":28,"t":"Petar mu poče govoriti: “Evo, mi sve ostavismo i pođosmo za tobom.”"},{"v":29,"t":"Reče Isus: “Zaista, kažem vam, nema ga tko ostavi kuću, ili braću, ili sestre, ili majku, ili oca, ili djecu, ili polja poradi mene i poradi evanđelja,"},{"v":30,"t":"a da ne bi sada, u ovom vremenu, s progonstvima primio stostruko kuća, i braće, i sestara, i majki, i djece, i polja - i u budućem vijeku život vječni."},{"v":31,"t":"A mnogi prvi bit će posljednji i posljednji prvi.”"},{"v":32,"t":"Putovali su tako uzlazeći u Jeruzalem. Isus je išao pred njima te bijahu zaprepašteni, a oni koji su išli za njima, prestrašeni. Tada Isus opet uze dvanaestoricu i poče im kazivati što će ga zadesiti:"},{"v":33,"t":"“Evo, uzlazimo u Jeruzalem i Sin Čovječji bit će predan glavarima svećeničkim i pismoznancima. Osudit će ga na smrt, predati poganima,"},{"v":34,"t":"izrugati i popljuvati. Izbičevat će ga, ubit će ga, ali on će nakon tri dana ustati.”"},{"v":35,"t":"I pristupe mu Jakov i Ivan, sinovi Zebedejevi, govoreći mu: “Učitelju, htjeli bismo da nam učiniš što te zaištemo.”"},{"v":36,"t":"A on će im: “Što hoćete da vam učinim?”"},{"v":37,"t":"Oni mu rekoše: “Daj nam da ti u slavi tvojoj sjednemo jedan zdesna, a drugi slijeva.”"},{"v":38,"t":"A Isus im reče: “Ne znate što ištete. Možete li piti čašu koju ja pijem, ili krstiti se krstom kojim se ja krstim?”"},{"v":39,"t":"Oni mu rekoše: “Možemo.” A Isus će im: “Čašu koju ja pijem pit ćete i krstom kojim se ja krstim bit ćete kršteni,"},{"v":40,"t":"ali sjesti meni zdesna ili slijeva nisam ja vlastan dati - to je onih kojima je pripravljeno.”"},{"v":41,"t":"Kad su to čula ostala desetorica, počeše se gnjeviti na Jakova i Ivana."},{"v":42,"t":"Zato ih Isus dozva i reče im: “Znate da oni koji se smatraju vladarima gospoduju svojim narodima i velikaši njihovi drže ih pod vlašću."},{"v":43,"t":"Nije tako među vama! Naprotiv, tko hoće da među vama bude najveći, neka vam bude poslužitelj!"},{"v":44,"t":"I tko hoće da među vama bude prvi, neka bude svima sluga."},{"v":45,"t":"Jer ni Sin Čovječji nije došao da bude služen, nego da služi i život svoj dade kao otkupninu za mnoge.”"},{"v":46,"t":"Dođu tako u Jerihon. Kad je Isus s učenicima i sa silnim mnoštvom izlazio iz Jerihona, kraj puta je sjedio slijepi prosjak Bartimej, sin Timejev."},{"v":47,"t":"Kad je čuo da je to Isus Nazarećanin, stane vikati: “Sine Davidov, Isuse, smiluj mi se!”"},{"v":48,"t":"Mnogi ga ušutkivahu, ali on još jače vikaše: “Sine Davidov, smiluj mi se!”"},{"v":49,"t":"Isus se zaustavi i reče: “Pozovite ga!” I pozovu slijepca sokoleći ga: “Ustani! Zove te!”"},{"v":50,"t":"On baci sa sebe ogrtač, skoči i dođe Isusu."},{"v":51,"t":"Isus ga upita: “Što hoćeš da ti učinim?” Slijepac mu reče: “Učitelju moj, da progledam.”"},{"v":52,"t":"Isus će mu: “Idi, vjera te tvoja spasila!” I on odmah progleda i uputi se za njim."}]},"11":{"fa":[{"v":1,"t":"و چون نزدیک به اورشلیم به بیت‌فاجی و بیت عنیا بر کوه زیتون رسیدند، دو نفراز شاگردان خود را فرستاده،"},{"v":2,"t":"بدیشان گفت: «بدین قریه‌ای که پیش روی شما است بروید وچون وارد آن شدید، درساعت کره الاغی را بسته خواهید یافت که تا به حال هیچ‌کس بر آن سوارنشده؛ آن را باز کرده، بیاورید."},{"v":3,"t":"و هرگاه کسی به شما گوید چرا چنین می‌کنید، گویید خداوندبدین احتیاج دارد؛ بی‌تامل آن را به اینجا خواهدفرستاد.»"},{"v":4,"t":"پس رفته کره‌ای بیرون دروازه درشارع عام بسته یافتند و آن را باز می‌کردند،"},{"v":5,"t":"که بعضی از حاضرین بدیشان گفتند: «چه‌کار داریدکه کره را باز می‌کنید؟»"},{"v":6,"t":"آن دو نفر چنانکه عیسی فرموده بود، بدیشان گفتند. پس ایشان را اجازت دادند."},{"v":7,"t":"آنگاه کره را به نزد عیسی آورده، رخت خود را بر آن افکندند تا بر آن سوار شد."},{"v":8,"t":"وبسیاری رختهای خود و بعضی شاخه‌ها ازدرختان بریده، بر راه گسترانیدند."},{"v":9,"t":"و آنانی که پیش و پس می‌رفتند، فریادکنان می‌گفتند: «هوشیعانا، مبارک باد کسی‌که به نام خداوندمی آید."},{"v":10,"t":"مبارک باد ملکوت پدر ما داود که می‌آید به اسم خداوند. هوشیعانا در اعلی علیین.»"},{"v":11,"t":"و عیسی وارد اورشلیم شده، به هیکل درآمد وبه همه‌چیز ملاحظه نمود. چون وقت شام شد باآن دوازده به بیت عنیا رفت."},{"v":12,"t":"بامدادان چون از بیت عنیا بیرون می‌آمدند، گرسنه شد."},{"v":13,"t":"ناگاه درخت انجیری که برگ داشت از دور دیده، آمد تا شاید چیزی بر آن بیابد. اما چون نزد آن رسید، جز برگ بر آن هیچ نیافت زیرا که موسم انجیر نرسیده بود."},{"v":14,"t":"پس عیسی توجه نموده، بدان فرمود: «از این پس تا به ابد، هیچ‌کس از تو میوه نخواهد خورد.» وشاگردانش شنیدند."},{"v":15,"t":"پس وارد اورشلیم شدند. و چون عیسی داخل هیکل گشت، به بیرون کردن آنانی که درهیکل خرید و فروش می‌کردند شروع نمود وتخت های صرافان و کرسیهای کبوترفروشان راواژگون ساخت،"},{"v":16,"t":"و نگذاشت که کسی با ظرفی از میان هیکل بگذرد،"},{"v":17,"t":"و تعلیم داده، گفت: «آیامکتوب نیست که خانه من خانه عبادت تمامی امتها نامیده خواهد شد؟ اما شما آن را مغاره دزدان ساخته‌اید.»"},{"v":18,"t":"چون روسای کهنه و کاتبان این را بشنیدند، در صدد آن شدند که او را چطور هلاک سازندزیرا که از وی ترسیدند چون که همه مردم ازتعلیم وی متحیر می‌بودند."},{"v":19,"t":"چون شام شد، از شهر بیرون رفت."},{"v":20,"t":"صبحگاهان، در اثنای راه، درخت انجیر رااز ریشه خشک یافتند."},{"v":21,"t":"پطرس به‌خاطر آورده، وی را گفت: «ای استاد، اینک درخت انجیری که نفرینش کردی خشک شده!»"},{"v":22,"t":"عیسی در جواب ایشان گفت: «به خدا ایمان آورید،"},{"v":23,"t":"زیرا که هرآینه به شما می‌گویم هر‌که بدین کوه گویدمنتقل شده، به دریا افکنده شو و در دل خود شک نداشته باشد بلکه یقین دارد که آنچه گویدمی شود، هرآینه هر‌آنچه گوید بدو عطا شود."},{"v":24,"t":"بنابراین به شما می‌گویم آنچه در عبادت سوال می‌کنید، یقین بدانید که آن را یافته‌اید و به شماعطا خواهد شد."},{"v":25,"t":"و وقتی که به دعا بایستید، هرگاه کسی به شما خطا کرده باشد، او را ببخشید تاآنکه پدر شما نیز که در آسمان است، خطایای شما را معاف دارد."},{"v":26,"t":"اما هرگاه شما نبخشید، پدر شما نیز که درآسمان است تقصیرهای شما را نخواهد بخشید.»"},{"v":27,"t":"و باز به اورشلیم آمدند. و هنگامی که او درهیکل می‌خرامید، روسای کهنه و کاتبان و مشایخ نزد وی آمده،"},{"v":28,"t":"گفتندش: «به چه قدرت این کارها را می‌کنی و کیست که این قدرت را به توداده است تا این اعمال را به‌جا آری؟»"},{"v":29,"t":"عیسی در جواب ایشان گفت: «من از شما نیز سخنی می پرسم، مرا جواب دهید تا من هم به شما گویم به چه قدرت این کارها را می‌کنم."},{"v":30,"t":"تعمید یحیی ازآسمان بود یا از انسان؟ مرا جواب دهید.»"},{"v":31,"t":"ایشان در دلهای خود تفکر نموده، گفتند: «اگرگوییم از آسمان بود، هرآینه گوید پس چرا بدوایمان نیاوردید."},{"v":32,"t":"و اگر گوییم از انسان بود، » ازخلق بیم داشتند از آنجا که همه یحیی را نبی‌ای برحق می‌دانستند."},{"v":33,"t":"پس در جواب عیسی گفتند: «نمی دانیم.» عیسی بدیشان جواب داد: «من هم شما را نمی گویم که به کدام قدرت این کارها را به‌جا می‌آورم.»"}],"en":[{"v":1,"t":"When they came near to Jerusalem, to Bethsphage and Bethany, at the Mount of Olives, he sent two of his disciples"},{"v":2,"t":"and said to them, “Go your way into the village that is opposite you. Immediately as you enter into it, you will find a young donkey tied, on which no one has sat. Untie him and bring him."},{"v":3,"t":"If anyone asks you, ‘Why are you doing this?’ say, ‘The Lord needs him;’ and immediately he will send him back here.”"},{"v":4,"t":"They went away, and found a young donkey tied at the door outside in the open street, and they untied him."},{"v":5,"t":"Some of those who stood there asked them, “What are you doing, untying the young donkey?”"},{"v":6,"t":"They said to them just as Jesus had said, and they let them go."},{"v":7,"t":"They brought the young donkey to Jesus and threw their garments on it, and Jesus sat on it."},{"v":8,"t":"Many spread their garments on the way, and others were cutting down branches from the trees and spreading them on the road."},{"v":9,"t":"Those who went in front and those who followed cried out, “Hosanna! Blessed is he who comes in the name of the Lord!"},{"v":10,"t":"Blessed is the kingdom of our father David that is coming in the name of the Lord! Hosanna in the highest!”"},{"v":11,"t":"Jesus entered into the temple in Jerusalem. When he had looked around at everything, it being now evening, he went out to Bethany with the twelve."},{"v":12,"t":"The next day, when they had come out from Bethany, he was hungry."},{"v":13,"t":"Seeing a fig tree afar off having leaves, he came to see if perhaps he might find anything on it. When he came to it, he found nothing but leaves, for it was not the season for figs."},{"v":14,"t":"Jesus told it, “May no one ever eat fruit from you again!” and his disciples heard it."},{"v":15,"t":"They came to Jerusalem, and Jesus entered into the temple and began to throw out those who sold and those who bought in the temple, and overthrew the money changers’ tables and the seats of those who sold the doves."},{"v":16,"t":"He would not allow anyone to carry a container through the temple."},{"v":17,"t":"He taught, saying to them, “Isn’t it written, ‘My house will be called a house of prayer for all the nations’? But you have made it a den of robbers!”"},{"v":18,"t":"The chief priests and the scribes heard it, and sought how they might destroy him. For they feared him, because all the multitude was astonished at his teaching."},{"v":19,"t":"When evening came, he went out of the city."},{"v":20,"t":"As they passed by in the morning, they saw the fig tree withered away from the roots."},{"v":21,"t":"Peter, remembering, said to him, “Rabbi, look! The fig tree which you cursed has withered away.”"},{"v":22,"t":"Jesus answered them, “Have faith in God."},{"v":23,"t":"For most certainly I tell you, whoever may tell this mountain, ‘Be taken up and cast into the sea,’ and doesn’t doubt in his heart, but believes that what he says is happening, he shall have whatever he says."},{"v":24,"t":"Therefore I tell you, all things whatever you pray and ask for, believe that you have received them, and you shall have them."},{"v":25,"t":"Whenever you stand praying, forgive, if you have anything against anyone; so that your Father, who is in heaven, may also forgive you your transgressions."},{"v":26,"t":"But if you do not forgive, neither will your Father in heaven forgive your transgressions.”"},{"v":27,"t":"They came again to Jerusalem, and as he was walking in the temple, the chief priests, the scribes, and the elders came to him,"},{"v":28,"t":"and they began saying to him, “By what authority do you do these things? Or who gave you this authority to do these things?”"},{"v":29,"t":"Jesus said to them, “I will ask you one question. Answer me, and I will tell you by what authority I do these things."},{"v":30,"t":"The baptism of John—was it from heaven, or from men? Answer me.”"},{"v":31,"t":"They reasoned with themselves, saying, “If we should say, ‘From heaven;’ he will say, ‘Why then did you not believe him?’"},{"v":32,"t":"If we should say, ‘From men’”—they feared the people, for all held John to really be a prophet."},{"v":33,"t":"They answered Jesus, “We don’t know.” Jesus said to them, “Neither will I tell you by what authority I do these things.”"}],"hr":[{"v":1,"t":"Kad se približe Jeruzalemu, Betfagi i Betaniji, do Maslinske gore, pošalje dva učenika"},{"v":2,"t":"i kaže im: “Hajdete u selo pred vama. Čim u nj uđete, naći ćete privezano magare koje još nitko nije zajahao. Odriješite ga i vodite."},{"v":3,"t":"Ako vam tko reče: 'Što to radite?' recite: 'Gospodinu treba', i odmah će ga ipak ovamo pustiti.”"},{"v":4,"t":"Otiđoše i nađoše magare privezano uz vrata vani na cesti i odriješe ga."},{"v":5,"t":"A neki od nazočnih upitaše: “Što radite? Što driješite magare?”"},{"v":6,"t":"Oni im odvrate kako im reče Isus. I pustiše ih."},{"v":7,"t":"I dovedu magare Isusu, prebace preko njega svoje haljine i on zajaha na nj."},{"v":8,"t":"Mnogi prostriješe svoje haljine po putu, a drugi narezaše zelenih grana po poljima."},{"v":9,"t":"I oni pred njim i oni za njim klicahu: “Hosana! Blagoslovljen Onaj koji dolazi u ime Gospodnje!"},{"v":10,"t":"Blagoslovljeno kraljevstvo oca našega Davida koji dolazi! Hosana u visinama!”"},{"v":11,"t":"I uđe u Jeruzalem, u Hram. I sve uokolo razgleda, pa kako već bijaše kasno, pođe s dvanaestoricom u Betaniju."},{"v":12,"t":"Sutradan su izlazili iz Betanije, a on ogladnje."},{"v":13,"t":"Ugleda izdaleka lisnatu smokvu i priđe ne bi li na njoj što našao. Ali došavši bliže, ne nađe ništa osim lišća jer ne bijaše vrijeme smokvama."},{"v":14,"t":"Tada reče smokvi: “Nitko nikada više ne jeo s tebe!” Čuli su to njegovi učenici."},{"v":15,"t":"Stignu tako u Jeruzalem. On uđe u Hram i stane izgoniti one koji su prodavali i kupovali u Hramu. Mjenjačima isprevrta stolove i prodavačima golubova klupe."},{"v":16,"t":"I ne dopusti da itko išta pronese kroz Hram."},{"v":17,"t":"Učio ih je i govorio: “Nije li pisano: Dom će se moj zvati Dom molitve za sve narode? A vi od njega načinili pećinu razbojničku!”"},{"v":18,"t":"Kada su za to dočuli glavari svećenički i pismoznanci, tražili su kako da ga pogube. Uistinu, bojahu ga se jer je sav narod bio očaran njegovim naukom."},{"v":19,"t":"A kad se uvečerilo, izlazili su iz grada."},{"v":20,"t":"Kad su ujutro prolazili mimo one smokve, opaze da je usahla do korijena."},{"v":21,"t":"Petar se prisjeti pa će Isusu: “Učitelju, pogledaj! Smokva koju si prokleo usahnu.”"},{"v":22,"t":"Isus im odvrati: “Imajte vjeru Božju."},{"v":23,"t":"Zaista, kažem vam, rekne li tko ovoj gori: 'Digni se i baci u more!' i u srcu svome ne posumnja, nego vjeruje da će se dogoditi to što kaže - doista, bit će mu!"},{"v":24,"t":"Stoga vam kažem: Sve što god zamolite i zaištete, vjerujte da ste postigli i bit će vam!"},{"v":25,"t":"No kad ustanete na molitvu, otpustite ako što imate protiv koga da i vama Otac vaš, koji je na nebesima, otpusti vaše prijestupke.”"},{"v":26,"t":"#"},{"v":27,"t":"I dođu opet u Jeruzalem. Dok je obilazio Hramom, dođu k njemu glavari svećenički, pismoznanci i starješine."},{"v":28,"t":"I govorahu mu: “Kojom vlašću to činiš? Ili tko ti dade tu vlast da to činiš?”"},{"v":29,"t":"A Isus im reče: “Jedno ću vas upitati. Odgovorite mi, pa ću vam kazati kojom vlašću ovo činim."},{"v":30,"t":"Krst Ivanov bijaše li od Neba ili od ljudi? Odgovorite mi!”"},{"v":31,"t":"A oni umovahu među sobom: “Reknemo li 'od Neba', odvratit će 'Zašto mu dakle ne povjerovaste?'"},{"v":32,"t":"Nego, da reknemo 'od ljudi!'” - Bojahu se mnoštva. Ta svi Ivana smatrahu doista prorokom."},{"v":33,"t":"I odgovore Isusu: “Ne znamo.” A Isus će im: “Ni ja vama neću kazati kojom vlašću ovo činim.”"}]},"12":{"fa":[{"v":1,"t":"پس به مثل‌ها به ایشان آغاز سخن نمودکه «شخصی تاکستانی غرس نموده، حصاری گردش کشید و چرخشتی بساخت وبرجی بنا کرده، آن را به دهقانان سپرد و سفر کرد."},{"v":2,"t":"و در موسم، نوکری نزد دهقانان فرستاد تا ازمیوه باغ از باغبانان بگیرد."},{"v":3,"t":"اما ایشان او را گرفته، زدند و تهی‌دست روانه نمودند."},{"v":4,"t":"باز نوکری دیگرنزد ایشان روانه نمود. او را نیز سنگسار کرده، سراو را شکستند و بی‌حرمت کرده، برگردانیدندش."},{"v":5,"t":"پس یک نفر دیگر فرستاده، او را نیز کشتند و بسادیگران را که بعضی را زدند و بعضی را به قتل رسانیدند."},{"v":6,"t":"و بالاخره یک پسر حبیب خود راباقی داشت. او را نزد ایشان فرستاده، گفت: پسرمرا حرمت خواهند داشت."},{"v":7,"t":"لیکن دهقانان با خودگفتند: این وارث است؛ بیایید او را بکشیم تامیراث از آن ما گردد."},{"v":8,"t":"پس او را گرفته، مقتول ساختند و او را بیرون از تاکستان افکندند."},{"v":9,"t":"پس صاحب تاکستان چه خواهد کرد؟ او خواهدآمد و آن باغبان را هلاک ساخته، باغ را به دیگران خواهد سپرد."},{"v":10,"t":"آیا این نوشته رانخوانده‌اید: سنگی که معمارانش رد کردند، همان سر زاویه گردید؟"},{"v":11,"t":"این از جانب خداوند شد و در نظر ما عجیب است."},{"v":12,"t":"آنگاه خواستند او را گرفتار سازند، اما از خلق می‌ترسیدند، زیرا می‌دانستند که این مثل رابرای ایشان آورد. پس او را واگذارده، برفتند."},{"v":13,"t":"و چند نفر از فریسیان و هیرودیان را نزدوی فرستادند تا او را به سخنی به دام آورند."},{"v":14,"t":"ایشان آمده، بدو گفتند: «ای استاد، ما را یقین است که تو راستگو هستی و از کسی باک نداری، چون که به ظاهر مردم نمی نگری بلکه طریق خدارا به راستی تعلیم می‌نمایی. جزیه دادن به قیصرجایز است یا نه؟ بدهیم یا ندهیم؟"},{"v":15,"t":"اما اوریاکاری ایشان را درک کرده، بدیشان گفت: «چرامرا امتحان می‌کنید؟ دیناری نزد من آرید تا آن راببینم.»"},{"v":16,"t":"چون آن را حاضر کردند، بدیشان گفت: «این صورت و رقم از آن کیست؟» وی راگفتند: «از آن قیصر.»"},{"v":17,"t":"عیسی در جواب ایشان گفت: «آنچه از قیصر است، به قیصر رد کنید وآنچه از خداست، به خدا.» و از او متعجب شدند."},{"v":18,"t":"و صدوقیان که منکر هستند نزد وی آمده، از او سوال نموده، گفتند:"},{"v":19,"t":"«ای استاد، موسی به ما نوشت که هرگاه برادر کسی بمیرد و زنی بازگذاشته، اولادی نداشته باشد، برادرش زن او رابگیرد تا از بهر برادر خود نسلی پیدا نماید."},{"v":20,"t":"پس هفت برادر بودند که نخستین، زنی گرفته، بمرد واولادی نگذاشت."},{"v":21,"t":"پس ثانی او را گرفته، هم بی‌اولاد فوت شد و همچنین سومی."},{"v":22,"t":"تا آنکه آن هفت او را گرفتند و اولادی نگذاشتند و بعد ازهمه، زن فوت شد."},{"v":23,"t":"پس در قیامت چون برخیزند، زن کدام‌یک از ایشان خواهد بود ازآنجهت که هر هفت، او را به زنی گرفته بودند؟»"},{"v":24,"t":"عیسی در جواب ایشان گفت: «آیا گمراه نیستید از آنرو که کتب و قوت خدا را نمی دانید؟"},{"v":25,"t":"زیرا هنگامی که از مردگان برخیزند، نه نکاح می‌کنند و نه منکوحه می‌گردند، بلکه مانندفرشتگان، در آسمان می‌باشند."},{"v":26,"t":"اما در باب مردگان که برمی خیزند، در کتاب موسی در ذکربوته نخوانده‌اید چگونه خدا او را خطاب کرده، گفت که منم خدای ابراهیم و خدای اسحاق وخدای یعقوب."},{"v":27,"t":"و او خدای مردگان نیست بلکه خدای زندگان است. پس شما بسیار گمراه شده‌اید.»"},{"v":28,"t":"و یکی از کاتبان، چون مباحثه ایشان را شنیده، دید که ایشان را جواب نیکو داد، پیش آمده، از او پرسید که «اول همه احکام کدام است؟»"},{"v":29,"t":"عیسی او را جواب داد که «اول همه احکام این است که بشنو‌ای اسرائیل، خداوندخدای ما خداوند واحد است."},{"v":30,"t":"و خداوندخدای خود را به تمامی دل و تمامی جان وتمامی خاطر و تمامی قوت خود محبت نما، که اول از احکام این است."},{"v":31,"t":"و دوم مثل اول است که همسایه خود را چون نفس خود محبت نما. بزرگتر از این دو، حکمی نیست.»"},{"v":32,"t":"کاتب وی راگفت: «آفرین‌ای استاد، نیکو گفتی، زیرا خداواحد است و سوای او دیگری نیست،"},{"v":33,"t":"و او رابه تمامی دل و تمامی فهم و تمامی نفس و تمامی قوت محبت نمودن و همسایه خود را مثل خودمحبت نمودن، از همه قربانی های سوختنی وهدایا افضل است.»"},{"v":34,"t":"چون عیسی بدید که عاقلانه جواب داد، به وی گفت: «از ملکوت خدادور نیستی.» و بعد از آن، هیچ‌کس جرات نکردکه از او سوالی کند."},{"v":35,"t":"و هنگامی که عیسی در هیکل تعلیم می‌داد، متوجه شده، گفت: «چگونه کاتبان می‌گویند که مسیح پسر داود است؟"},{"v":36,"t":"و حال آنکه خود داود در روح‌القدس می‌گوید که خداوند به خداوند من گفت برطرف راست من بنشین تا دشمنان تو را پای انداز تو سازم؟"},{"v":37,"t":"خودداود او را خداوند می‌خواند؛ پس چگونه او راپسر می‌باشد؟» و عوام الناس کلام او را به خشنودی می‌شنیدند."},{"v":38,"t":"پس در تعلیم خود گفت: «از کاتبان احتیاطکنید که خرامیدن در لباس دراز و تعظیم های دربازارها"},{"v":39,"t":"و کرسی های اول در کنایس و جایهای صدر در ضیافت‌ها را دوست می‌دارند."},{"v":40,"t":"اینان که خانه های بیوه‌زنان را می‌بلعند و نماز را به ریاطول می‌دهند، عقوبت شدیدتر خواهند یافت.»"},{"v":41,"t":"و عیسی در مقابل بیت‌المال نشسته، نظاره می‌کرد که مردم به چه وضع پول به بیت‌المال می‌اندازند؛ و بسیاری از دولتمندان، بسیارمی انداختند."},{"v":42,"t":"آنگاه بیوه‌زنی فقیر آمده، دوفلس که یک ربع باشد انداخت."},{"v":43,"t":"پس شاگردان خود را پیش خوانده، به ایشان گفت: «هرآینه به شما می‌گویم این بیوه‌زن مسکین از همه آنانی که در خزانه انداختند، بیشتر داد."},{"v":44,"t":"زیرا که همه ایشان از زیادتی خود دادند، لیکن این زن ازحاجتمندی خود، آنچه داشت انداخت، یعنی تمام معیشت خود را.»"}],"en":[{"v":1,"t":"He began to speak to them in parables. “A man planted a vineyard, put a hedge around it, dug a pit for the wine press, built a tower, rented it out to a farmer, and went into another country."},{"v":2,"t":"When it was time, he sent a servant to the farmer to get from the farmer his share of the fruit of the vineyard."},{"v":3,"t":"They took him, beat him, and sent him away empty."},{"v":4,"t":"Again, he sent another servant to them; and they threw stones at him, wounded him in the head, and sent him away shamefully treated."},{"v":5,"t":"Again he sent another, and they killed him, and many others, beating some, and killing some."},{"v":6,"t":"Therefore still having one, his beloved son, he sent him last to them, saying, ‘They will respect my son.’"},{"v":7,"t":"But those farmers said among themselves, ‘This is the heir. Come, let’s kill him, and the inheritance will be ours.’"},{"v":8,"t":"They took him, killed him, and cast him out of the vineyard."},{"v":9,"t":"What therefore will the lord of the vineyard do? He will come and destroy the farmers, and will give the vineyard to others."},{"v":10,"t":"Haven’t you even read this Scripture: ‘The stone which the builders rejected was made the head of the corner."},{"v":11,"t":"This was from the Lord. It is marvelous in our eyes’?”"},{"v":12,"t":"They tried to seize him, but they feared the multitude; for they perceived that he spoke the parable against them. They left him and went away."},{"v":13,"t":"They sent some of the Pharisees and the Herodians to him, that they might trap him with words."},{"v":14,"t":"When they had come, they asked him, “Teacher, we know that you are honest, and don’t defer to anyone; for you aren’t partial to anyone, but truly teach the way of God. Is it lawful to pay taxes to Caesar, or not?"},{"v":15,"t":"Shall we give, or shall we not give?” But he, knowing their hypocrisy, said to them, “Why do you test me? Bring me a denarius, that I may see it.”"},{"v":16,"t":"They brought it. He said to them, “Whose is this image and inscription?” They said to him, “Caesar’s.”"},{"v":17,"t":"Jesus answered them, “Render to Caesar the things that are Caesar’s, and to God the things that are God’s.” They marveled greatly at him."},{"v":18,"t":"Some Sadducees, who say that there is no resurrection, came to him. They asked him, saying,"},{"v":19,"t":"“Teacher, Moses wrote to us, ‘If a man’s brother dies and leaves a wife behind him, and leaves no children, that his brother should take his wife and raise up offspring for his brother.’"},{"v":20,"t":"There were seven brothers. The first took a wife, and dying left no offspring."},{"v":21,"t":"The second took her, and died, leaving no children behind him. The third likewise;"},{"v":22,"t":"and the seven took her and left no children. Last of all the woman also died."},{"v":23,"t":"In the resurrection, when they rise, whose wife will she be of them? For the seven had her as a wife.”"},{"v":24,"t":"Jesus answered them, “Isn’t this because you are mistaken, not knowing the Scriptures nor the power of God?"},{"v":25,"t":"For when they will rise from the dead, they neither marry nor are given in marriage, but are like angels in heaven."},{"v":26,"t":"But about the dead, that they are raised, haven’t you read in the book of Moses about the Bush, how God spoke to him, saying, ‘I am the God of Abraham, the God of Isaac, and the God of Jacob’?"},{"v":27,"t":"He is not the God of the dead, but of the living. You are therefore badly mistaken.”"},{"v":28,"t":"One of the scribes came and heard them questioning together, and knowing that he had answered them well, asked him, “Which commandment is the greatest of all?”"},{"v":29,"t":"Jesus answered, “The greatest is: ‘Hear, Israel, the Lord our God, the Lord is one."},{"v":30,"t":"You shall love the Lord your God with all your heart, with all your soul, with all your mind, and with all your strength.’ This is the first commandment."},{"v":31,"t":"The second is like this: ‘You shall love your neighbor as yourself.’ There is no other commandment greater than these.”"},{"v":32,"t":"The scribe said to him, “Truly, teacher, you have said well that he is one, and there is none other but he;"},{"v":33,"t":"and to love him with all the heart, with all the understanding, all the soul, and with all the strength, and to love his neighbor as himself, is more important than all whole burnt offerings and sacrifices.”"},{"v":34,"t":"When Jesus saw that he answered wisely, he said to him, “You are not far from God’s Kingdom.” No one dared ask him any question after that."},{"v":35,"t":"Jesus responded, as he taught in the temple, “How is it that the scribes say that the Christ is the son of David?"},{"v":36,"t":"For David himself said in the Holy Spirit, ‘The Lord said to my Lord, “Sit at my right hand, until I make your enemies the footstool of your feet.”’"},{"v":37,"t":"Therefore David himself calls him Lord, so how can he be his son?” The common people heard him gladly."},{"v":38,"t":"In his teaching he said to them, “Beware of the scribes, who like to walk in long robes, and to get greetings in the marketplaces,"},{"v":39,"t":"and to get the best seats in the synagogues and the best places at feasts,"},{"v":40,"t":"those who devour widows’ houses, and for a pretense make long prayers. These will receive greater condemnation.”"},{"v":41,"t":"Jesus sat down opposite the treasury and saw how the multitude cast money into the treasury. Many who were rich cast in much."},{"v":42,"t":"A poor widow came and she cast in two small brass coins, which equal a quadrans coin."},{"v":43,"t":"He called his disciples to himself and said to them, “Most certainly I tell you, this poor widow gave more than all those who are giving into the treasury,"},{"v":44,"t":"for they all gave out of their abundance, but she, out of her poverty, gave all that she had to live on.”"}],"hr":[{"v":1,"t":"I uze im zboriti u prispodobama: Čovjek vinograd posadi, ogradom ogradi, iskopa tijesak i kulu podiže pa ga iznajmi vinogradarima i otputova."},{"v":2,"t":"I u svoje vrijeme posla vinogradarima slugu da od njih uzme dio uroda vinogradarskoga."},{"v":3,"t":"A oni ga pograbiše, istukoše i otposlaše praznih ruku."},{"v":4,"t":"I opet posla k njima drugog slugu: i njemu razbiše glavu i izružiše ga."},{"v":5,"t":"Trećega također posla: njega ubiše. Tako i mnoge druge: jedne istukoše, druge pobiše.”"},{"v":6,"t":"“Još jednoga imaše, sina ljubljenoga. Njega naposljetku posla k njima misleći: 'Poštovat će sina moga.'"},{"v":7,"t":"Ali ti vinogradari među sobom rekoše: 'Ovo je baštinik! Hajde da ga ubijemo i baština će biti naša.'"},{"v":8,"t":"I pograbe ga, ubiju i izbace iz vinograda.”"},{"v":9,"t":"“Što li će učiniti gospodar vinograda? Doći će i pobiti te vinogradare i dati vinograd drugima."},{"v":10,"t":"Niste li čitali ovo Pismo: Kamen što ga odbaciše graditelji, postade kamen zaglavni."},{"v":11,"t":"Gospodnje je to djelo - kakvo čudo u očima našim!”"},{"v":12,"t":"I tražili su da ga uhvate, ali se pobojaše mnoštva. Razumješe da je protiv njih izrekao prispodobu pa ga ostave i odu."},{"v":13,"t":"I pošalju k njemu neke od farizeja i herodovaca da ga uhvate u riječi."},{"v":14,"t":"Oni dođu i kažu mu: “Učitelju, znamo da si istinit i ne mariš tko je tko jer nisi pristran, nego po istini učiš putu Božjemu. Je li dopušteno dati porez caru ili nije? Da damo ili da ne damo?”"},{"v":15,"t":"A on im reče prozirući njihovo licemjerje: “Što me iskušavate? Donesite mi denar da vidim!”"},{"v":16,"t":"Oni doniješe. I reče im: “Čija je ovo slika i natpis?” A oni će mu: “Carev.”"},{"v":17,"t":"A Isus im reče: “Caru podajte carevo, a Bogu Božje!” I divili su mu se."},{"v":18,"t":"Dođu k njemu saduceji, koji vele da nema uskrsnuća, i upitaju ga:"},{"v":19,"t":"“Učitelju, Mojsije nam napisa: Umre li čiji brat i ostavi ženu, a ne ostavi djeteta, neka njegov brat uzme tu ženu te podigne porod bratu svomu."},{"v":20,"t":"Sedmero braće bijaše. Prvi uze ženu i umrije ne ostavivši poroda."},{"v":21,"t":"I drugi je uze te umrije ne ostavivši poroda. I treći jednako tako."},{"v":22,"t":"I sedmorica ne ostaviše poroda. Najposlije i žena umrije."},{"v":23,"t":"Komu će biti žena o uskrsnuću, kad uskrsnu? Jer sedmorica su je imala za ženu.”"},{"v":24,"t":"Reče im Isus: “Niste li u zabludi zbog toga što ne razumijete Pisama ni sile Božje?"},{"v":25,"t":"Ta kad od mrtvih ustaju, niti se žene niti udavaju, nego su kao anđeli na nebesima."},{"v":26,"t":"A što se tiče mrtvih, da ustaju, niste li čitali u knjizi Mojsijevoj ono o grmu, kako Mojsiju reče Bog: Ja sam Bog Abrahamov i Bog Izakov i Bog Jakovljev?"},{"v":27,"t":"Nije on Bog mrtvih, nego živih. Uvelike se varate.”"},{"v":28,"t":"Tada pristupi jedan od pismoznanaca koji je slušao njihovu raspravu. Vidjevši da im je dobro odgovorio, upita ga: “Koja je zapovijed prva od sviju?”"},{"v":29,"t":"Isus odgovori: “Prva je: Slušaj, Izraele! Gospodin Bog naš Gospodin je jedini."},{"v":30,"t":"Zato ljubi Gospodina Boga svojega iz svega srca svojega, i iz sve duše svoje, i iz svega uma svoga, i iz sve snage svoje!”"},{"v":31,"t":"“Druga je: Ljubi svoga bližnjega kao sebe samoga. Nema druge zapovijedi veće od tih.”"},{"v":32,"t":"Nato će mu pismoznanac: “Dobro, učitelju! Po istini si kazao: On je jedini, nema drugoga osim njega."},{"v":33,"t":"Njega ljubiti iz svega srca, iz svega razuma i iz sve snage i ljubiti bližnjega kao sebe samoga - više je nego sve paljenice i žrtve.”"},{"v":34,"t":"Kad Isus vidje kako je pametno odgovorio, reče mu: “Nisi daleko od kraljevstva Božjega!” I nitko se više nije usuđivao pitati ga."},{"v":35,"t":"A naučavajući u Hramu, uze Isus govoriti: “Kako pismoznanci kažu da je Krist sin Davidov?"},{"v":36,"t":"A sam David reče u Duhu Svetome: Reče Gospod Gospodinu mojemu: 'Sjedni mi zdesna dok ne položim neprijatelje tvoje za podnožje nogama tvojim!'"},{"v":37,"t":"Sam ga David zove Gospodinom. Kako mu je onda sin?” Silan ga je svijet s užitkom slušao."},{"v":38,"t":"A on im u pouci svojoj govoraše: “Čuvajte se pismoznanaca, koji rado idu u dugim haljinama, vole pozdrave na trgovima,"},{"v":39,"t":"prva sjedala u sinagogama i pročelja na gozbama;"},{"v":40,"t":"proždiru kuće udovičke, još pod izlikom dugih molitava. Stići će ih to oštrija osuda!”"},{"v":41,"t":"Potom sjede nasuprot riznici te promatraše kako narod baca sitniš u riznicu. Mnogi bogataši bacahu mnogo."},{"v":42,"t":"Dođe i neka siromašna udovica i baci dva novčića, to jest jedan kvadrant."},{"v":43,"t":"Tada dozove svoje učenike i reče im: “Doista, kažem vam, ova je sirota udovica ubacila više od svih koji ubacuju u riznicu."},{"v":44,"t":"Svi su oni zapravo ubacili od svoga suviška, a ona je od svoje sirotinje ubacila sve što je imala, sav svoj žitak.”"}]},"13":{"fa":[{"v":1,"t":"و چون او از هیکل بیرون می‌رفت، یکی از شاگردانش بدو گفت: «ای استادملاحظه فرما چه نوع سنگها و چه عمارت ها است!»"},{"v":2,"t":"عیسی در جواب وی گفت: «آیا این عمارت های عظیمه را می‌نگری؟ بدان که سنگی بر سنگی گذارده نخواهد شد، مگر آنکه به زیرافکنده شود!»"},{"v":3,"t":"و چون او بر کوه زیتون، مقابل هیکل نشسته بود، پطرس و یعقوب و یوحنا و اندریاس سر ازوی پرسیدند:"},{"v":4,"t":"«ما را خبر بده که این امور کی واقع می‌شود و علامت نزدیک شدن این امورچیست؟»"},{"v":5,"t":"آنگاه عیسی در جواب ایشان سخن آغازکرد که «زنهار کسی شما را گمراه نکند!"},{"v":6,"t":"زیرا که بسیاری به نام من آمده، خواهند گفت که من هستم و بسیاری را گمراه خواهند نمود."},{"v":7,"t":"اما چون جنگها و اخبار جنگها را بشنوید، مضطرب مشوید زیرا که وقوع این حوادث ضروری است لیکن انتها هنوز نیست."},{"v":8,"t":"زیرا که امتی بر امتی ومملکتی بر مملکتی خواهند برخاست و زلزله هادر جایها حادث خواهد شد و قحطی‌ها واغتشاش‌ها پدید می‌آید؛ و اینها ابتدای دردهای زه می‌باشد."},{"v":9,"t":"«لیکن شما از برای خود احتیاط کنید زیرا که شما را به شوراها خواهند سپرد و در کنایس تازیانه‌ها خواهند زد و شما را پیش حکام وپادشاهان بخاطر من حاضر خواهند کرد تا برایشان شهادتی شود."},{"v":10,"t":"و لازم است که انجیل اول بر تمامی امتها موعظه شود."},{"v":11,"t":"و چون شما راگرفته، تسلیم کنند، میندیشید که چه بگویید ومتفکر مباشید بلکه آنچه در آن ساعت به شما عطاشود، آن را گویید زیرا گوینده شما نیستید بلکه روح‌القدس است."},{"v":12,"t":"آنگاه برادر، برادر را و پدر، فرزند را به هلاکت خواهند سپرد و فرزندان بروالدین خود برخاسته، ایشان را به قتل خواهندرسانید."},{"v":13,"t":"و تمام خلق بجهت اسم من شما رادشمن خواهند داشت. اما هر‌که تا به آخر صبرکند، همان نجات یابد."},{"v":14,"t":"«پس چون مکروه ویرانی را که به زبان دانیال نبی گفته شده است، در جایی که نمی بایدبرپا بینید - آنکه می‌خواند بفهمد - آنگاه آنانی که در یهودیه می‌باشند، به کوهستان فرار کنند،"},{"v":15,"t":"و هر‌که بر بام باشد، به زیر نیاید و به خانه داخل نشود تا چیزی از آن ببرد،"},{"v":16,"t":"و آنکه در مزرعه است، برنگردد تا رخت خود را بردارد."},{"v":17,"t":"اما وای بر آبستنان و شیر دهندگان در آن ایام."},{"v":18,"t":"و دعاکنید که فرار شما در زمستان نشود،"},{"v":19,"t":"زیرا که درآن ایام، چنان مصیبتی خواهد شد که از ابتدای خلقتی که خدا آفرید تاکنون نشده و نخواهد شد."},{"v":20,"t":"و اگر خداوند آن روزها را کوتاه نکردی، هیچ بشری نجات نیافتی. لیکن بجهت برگزیدگانی که انتخاب نموده است، آن ایام را کوتاه ساخت."},{"v":21,"t":"«پس هرگاه کسی به شما گوید اینک مسیح در اینجاست یا اینک در آنجا، باور مکنید."},{"v":22,"t":"زانرو که مسیحان دروغ و انبیای کذبه ظاهرشده، آیات و معجزات از ایشان صادر خواهدشد، بقسمی که اگر ممکن بودی، برگزیدگان را هم گمراه نمودندی."},{"v":23,"t":"لیکن شما برحذر باشید!"},{"v":24,"t":"و درآن روزهای بعد از آن مصیبت خورشید تاریک گردد و ماه نور خود را بازگیرد،"},{"v":25,"t":"و ستارگان ازآسمان فرو ریزند و قوای افلاک متزلزل خواهدگشت."},{"v":26,"t":"آنگاه پسر انسان را بینند که با قوت وجلال عظیم بر ابرها می‌آید."},{"v":27,"t":"در آن وقت، فرشتگان خود را از جهات اربعه از انتهای زمین تابه اقصای فلک فراهم خواهد آورد."},{"v":28,"t":"«الحال از درخت انجیر مثلش را فراگیریدکه چون شاخه‌اش نازک شده، برگ می‌آوردمی دانید که تابستان نزدیک است."},{"v":29,"t":"همچنین شما نیز چون این چیزها را واقع بینید، بدانید که نزدیک بلکه بر در است."},{"v":30,"t":"هرآینه به شمامی گویم تا جمیع این حوادث واقع نشود، این فرقه نخواهند گذشت."},{"v":31,"t":"آسمان و زمین زایل می‌شود، لیکن کلمات من هرگز زایل نشود."},{"v":32,"t":"ولی از آن روز و ساعت غیر از پدرهیچ‌کس اطلاع ندارد، نه فرشتگان در آسمان و نه پسر هم."},{"v":33,"t":"«پس برحذر و بیدار شده، دعا کنیدزیرا نمی دانید که آن وقت کی می‌شود."},{"v":34,"t":"مثل کسی‌که عازم سفر شده، خانه خود را واگذارد وخادمان خود را قدرت داده، هر یکی را به شغلی خاص مقرر نماید و دربان را امر فرماید که بیداربماند."},{"v":35,"t":"پس بیدار باشید زیرا نمی دانید که در چه وقت صاحب‌خانه می‌آید، در شام یا نصف شب یا بانگ خروس یا صبح."},{"v":36,"t":"مبادا ناگهان آمده شما را خفته یابد."},{"v":37,"t":"اما آنچه به شما می‌گویم، به همه می‌گویم: بیدار باشید!»"}],"en":[{"v":1,"t":"As he went out of the temple, one of his disciples said to him, “Teacher, see what kind of stones and what kind of buildings!”"},{"v":2,"t":"Jesus said to him, “Do you see these great buildings? There will not be left here one stone on another, which will not be thrown down.”"},{"v":3,"t":"As he sat on the Mount of Olives opposite the temple, Peter, James, John, and Andrew asked him privately,"},{"v":4,"t":"“Tell us, when will these things be? What is the sign that these things are all about to be fulfilled?”"},{"v":5,"t":"Jesus, answering, began to tell them, “Be careful that no one leads you astray."},{"v":6,"t":"For many will come in my name, saying, ‘I am he!’ and will lead many astray."},{"v":7,"t":"“When you hear of wars and rumors of wars, don’t be troubled. For those must happen, but the end is not yet."},{"v":8,"t":"For nation will rise against nation, and kingdom against kingdom. There will be earthquakes in various places. There will be famines and troubles. These things are the beginning of birth pains."},{"v":9,"t":"“But watch yourselves, for they will deliver you up to councils. You will be beaten in synagogues. You will stand before rulers and kings for my sake, for a testimony to them."},{"v":10,"t":"The Good News must first be preached to all the nations."},{"v":11,"t":"When they lead you away and deliver you up, don’t be anxious beforehand or premeditate what you will say, but say whatever will be given you in that hour. For it is not you who speak, but the Holy Spirit."},{"v":12,"t":"“Brother will deliver up brother to death, and the father his child. Children will rise up against parents and cause them to be put to death."},{"v":13,"t":"You will be hated by all men for my name’s sake, but he who endures to the end will be saved."},{"v":14,"t":"“But when you see the abomination of desolation, spoken of by Daniel the prophet, standing where it ought not” (let the reader understand), “then let those who are in Judea flee to the mountains,"},{"v":15,"t":"and let him who is on the housetop not go down, nor enter in, to take anything out of his house."},{"v":16,"t":"Let him who is in the field not return back to take his cloak."},{"v":17,"t":"But woe to those who are with child and to those who nurse babies in those days!"},{"v":18,"t":"Pray that your flight won’t be in the winter."},{"v":19,"t":"For in those days there will be oppression, such as there has not been the like from the beginning of the creation which God created until now, and never will be."},{"v":20,"t":"Unless the Lord had shortened the days, no flesh would have been saved; but for the sake of the chosen ones, whom he picked out, he shortened the days."},{"v":21,"t":"Then if anyone tells you, ‘Look, here is the Christ!’ or, ‘Look, there!’ don’t believe it."},{"v":22,"t":"For false christs and false prophets will arise and will show signs and wonders, that they may lead astray, if possible, even the chosen ones."},{"v":23,"t":"But you watch. “Behold, I have told you all things beforehand."},{"v":24,"t":"But in those days, after that oppression, the sun will be darkened, the moon will not give its light,"},{"v":25,"t":"the stars will be falling from the sky, and the powers that are in the heavens will be shaken."},{"v":26,"t":"Then they will see the Son of Man coming in clouds with great power and glory."},{"v":27,"t":"Then he will send out his angels, and will gather together his chosen ones from the four winds, from the ends of the earth to the ends of the sky."},{"v":28,"t":"“Now from the fig tree, learn this parable. When the branch has now become tender and produces its leaves, you know that the summer is near;"},{"v":29,"t":"even so you also, when you see these things coming to pass, know that it is near, at the doors."},{"v":30,"t":"Most certainly I say to you, this generation will not pass away until all these things happen."},{"v":31,"t":"Heaven and earth will pass away, but my words will not pass away."},{"v":32,"t":"“But of that day or that hour no one knows—not even the angels in heaven, nor the Son, but only the Father."},{"v":33,"t":"Watch, keep alert, and pray; for you don’t know when the time is."},{"v":34,"t":"“It is like a man traveling to another country, having left his house and given authority to his servants, and to each one his work, and also commanded the doorkeeper to keep watch."},{"v":35,"t":"Watch therefore, for you don’t know when the lord of the house is coming—whether at evening, or at midnight, or when the rooster crows, or in the morning;"},{"v":36,"t":"lest, coming suddenly, he might find you sleeping."},{"v":37,"t":"What I tell you, I tell all: Watch!”"}],"hr":[{"v":1,"t":"Kad je izlazio iz Hrama, rekne mu jedan od njegovih učenika: “Učitelju, gledaj! Kakva li kamenja, kakvih li zdanja!”"},{"v":2,"t":"Isus mu odvrati: “Vidiš li ta veličanstvena zdanja? Ne, neće se ostaviti ni kamen na kamenu nerazvaljen.”"},{"v":3,"t":"Dok je zatim na Maslinskoj gori sjedio sučelice Hramu, upitaju ga nasamo Petar, Jakov, Ivan i Andrija:"},{"v":4,"t":"“Reci nam kada će to biti i na koji se znak sve to ima svršiti?”"},{"v":5,"t":"Tada im Isus poče govoriti: “Pazite da vas tko ne zavede."},{"v":6,"t":"Mnogi će doći u moje ime i govoriti: Ja sam! I mnoge će zavesti."},{"v":7,"t":"Kada pak čujete za ratove i za glasove o ratovima, ne uznemirujte se. Treba da se to dogodi, ali to još nije svršetak.”"},{"v":8,"t":"“Narod će ustati protiv naroda, kraljevstvo protiv kraljevstva. Bit će potresa po raznim mjestima, bit će gladi. To je početak trudova.”"},{"v":9,"t":"“Vi pak pazite sami na sebe. Predavat će vas vijećima i tući vas u sinagogama, pred upraviteljima i kraljevima stajat ćete zbog mene, njima za svjedočanstvo."},{"v":10,"t":"A treba da se najprije svim narodima propovijeda evanđelje.”"},{"v":11,"t":"“Kad vas budu vodili na izručenje, ne brinite se unaprijed što ćete govoriti, nego govorite što vam bude dano u onaj čas. Ta niste vi koji govorite, nego Duh Sveti."},{"v":12,"t":"Predavat će na smrt brat brata i otac sina. Djeca će ustajati na roditelje i ubijati ih."},{"v":13,"t":"Svi će vas zamrziti zbog imena moga. Ali tko ustraje do svršetka, bit će spašen.”"},{"v":14,"t":"“I kad vidite da grozota pustoši stoluje gdje joj nije mjesto - tko čita, neka razumije - koji se tada zateknu u Judeji, neka bježe u gore!"},{"v":15,"t":"Tko bude na krovu, neka ne silazi i ne ulazi u kuću da iz nje što uzme."},{"v":16,"t":"I tko bude u polju, neka se ne okreće natrag da uzme ogrtač!”"},{"v":17,"t":"“Jao trudnicama i dojiljama u one dane!"},{"v":18,"t":"A molite da to ne bude zimi"},{"v":19,"t":"jer će onih dana biti tjeskoba kakve ne bi od početka stvorenja, koje stvori Bog, sve do sada, a neće je ni biti."},{"v":20,"t":"I kad Gospodin ne bi skratio dane one, nitko se ne bi spasio. No poradi izabranih, koje on sebi izabra, skratio je on te dane.”"},{"v":21,"t":"Ako vam tada tko rekne: 'Evo Krista ovdje! Eno ondje!' - ne vjerujte."},{"v":22,"t":"Ustat će doista lažni kristi i lažni proroci i tvorit će znamenja i čudesa da, bude li moguće, zavedu izabrane."},{"v":23,"t":"Vi dakle budite na oprezu! Evo, prorekao sam vam sve!”"},{"v":24,"t":"Nego, u one dane, nakon one nevolje, sunce će pomrčati i mjesec neće više svijetljeti"},{"v":25,"t":"a zvijezde će s neba padati i sile će se nebeske poljuljati."},{"v":26,"t":"Tada će ugledati Sina Čovječjega gdje dolazi na oblacima s velikom moći i slavom."},{"v":27,"t":"I razaslat će anđele i sabrati svoje izabranike s četiri vjetra, s kraja zemlje do na kraj neba.”"},{"v":28,"t":"A od smokve se naučite prispodobi! Kad joj grana već omekša i lišće potjera, znate: ljeto je blizu."},{"v":29,"t":"Tako i vi kad vidite da se to zbiva, znajte: blizu je, na vratima!"},{"v":30,"t":"Zaista, kažem vam, ne, neće uminuti naraštaj ovaj dok se sve to ne zbude."},{"v":31,"t":"Nebo će i zemlja uminuti, ali riječi moje ne, neće uminuti.”"},{"v":32,"t":"“A o onom danu i času nitko ne zna, pa ni anđeli na nebu, ni Sin, nego samo Otac.”"},{"v":33,"t":"“Pazite! Bdijte jer ne znate kada je čas."},{"v":34,"t":"Kao kad ono čovjek neki polazeći na put ostavi svoju kuću, upravu povjeri slugama, svakomu svoj posao, a vrataru zapovjedi da bdije."},{"v":35,"t":"Bdijte, dakle, jer ne znate kad će se domaćin vratiti - da li uvečer ili o ponoći, da li za prvih pijetlova ili ujutro -"},{"v":36,"t":"da vas ne bi našao pozaspale ako iznenada dođe.”"},{"v":37,"t":"“Što vama kažem, svima kažem: Bdijte!”"}]},"14":{"fa":[{"v":1,"t":"و بعد از دو روز، عید فصح و فطیر بودکه روسای کهنه و کاتبان مترصد بودندکه به چه حیله او را دستگیر کرده، به قتل رسانند."},{"v":2,"t":"لیکن می‌گفتند: «نه در عید مبادا در قوم اغتشاشی پدید آید.»"},{"v":3,"t":"و هنگامی که او در بیت عنیا در خانه شمعون ابرص به غذا نشسته بود، زنی با شیشه‌ای از عطرگرانبها از سنبل خالص آمده، شیشه را شکسته، برسر وی ریخت."},{"v":4,"t":"و بعضی در خود خشم نموده، گفتند: «چرا این عطر تلف شد؟"},{"v":5,"t":"زیرا ممکن بوداین عطر زیادتر از سیصد دینار فروخته، به فقراداده شود.» و آن زن را سرزنش نمودند."},{"v":6,"t":"اماعیسی گفت: «او را واگذارید! از برای چه او رازحمت می‌دهید؟ زیرا که با من کاری نیکو کرده است،"},{"v":7,"t":"زیرا که فقرا را همیشه با خود دارید وهرگاه بخواهید می‌توانید با ایشان احسان کنید، لیکن مرا با خود دائم ندارید."},{"v":8,"t":"آنچه در قوه اوبود کرد، زیرا که جسد مرا بجهت دفن، پیش تدهین کرد."},{"v":9,"t":"هرآینه به شما می‌گویم در هر جایی از تمام عالم که به این انجیل موعظه شود، آنچه این زن کرد نیز بجهت یادگاری وی مذکور خواهد شد.»"},{"v":10,"t":"پس یهودای اسخریوطی که یکی از آن دوازده بود، به نزد روسای کهنه رفت تا او رابدیشان تسلیم کند."},{"v":11,"t":"ایشان سخن او را شنیده، شاد شدند و بدو وعده دادند که نقدی بدو بدهند. و او در صدد فرصت موافق برای گرفتاری وی برآمد."},{"v":12,"t":"و روز اول از عید فطیر که در آن فصح راذبح می‌کردند، شاگردانش به وی گفتند: «کجامی خواهی برویم تدارک بینیم تا فصح رابخوری؟»"},{"v":13,"t":"پس دو نفر از شاگردان خود رافرستاده، بدیشان گفت: «به شهر بروید و شخصی با سبوی آب به شما خواهد برخورد. از عقب وی بروید،"},{"v":14,"t":"و به هرجایی که درآید صاحب‌خانه راگویید: استاد می‌گوید مهمانخانه کجا است تافصح را با شاگردان خود آنجا صرف کنم؟"},{"v":15,"t":"و اوبالاخانه بزرگ مفروش و آماده به شما نشان می‌دهد. آنجا از بهر ما تدارک بینید.»"},{"v":16,"t":"شاگردانش روانه شدند و به شهر رفته، چنانکه او فرموده بود، یافتند و فصح را آماده ساختند."},{"v":17,"t":"شامگاهان با آن دوازده آمد."},{"v":18,"t":"و چون نشسته غذا می‌خوردند، عیسی گفت: «هرآینه به شما می‌گویم که، یکی از شما که با من غذامی خورد، مرا تسلیم خواهد کرد.»"},{"v":19,"t":"ایشان غمگین گشته، یک یک گفتن گرفتند که آیا من آنم و دیگری که آیا من هستم."},{"v":20,"t":"او در جواب ایشان گفت: «یکی از دوازده که با من دست در قاب فروبرد!"},{"v":21,"t":"به درستی که پسر انسان بطوری که درباره او مکتوب است، رحلت می‌کند. لیکن وای بر آن کسی‌که پسر انسان به واسطه او تسلیم شود. او رابهتر می‌بود که تولد نیافتی.»"},{"v":22,"t":"و چون غذا می‌خوردند، عیسی نان راگرفته، برکت داد و پاره کرده، بدیشان داد و گفت: «بگیرید و بخورید که این جسد من است.»"},{"v":23,"t":"وپیاله‌ای گرفته، شکر نمود و به ایشان داد و همه ازآن آشامیدند"},{"v":24,"t":"و بدیشان گفت: «این است خون من از عهد جدید که در راه بسیاری ریخته می‌شود."},{"v":25,"t":"هرآینه به شما می‌گویم بعد از این ازعصیر انگور نخورم تا آن روزی که در ملکوت خدا آن را تازه بنوشم."},{"v":26,"t":"و بعد از خواندن تسبیح، به سوی کوه زیتون بیرون رفتند."},{"v":27,"t":"عیسی ایشان را گفت: «همانا همه شما امشب در من لغزش خورید، زیرامکتوب است شبان را می‌زنم و گوسفندان پراکنده خواهند شد."},{"v":28,"t":"اما بعد از برخاستنم، پیش از شمابه جلیل خواهم رفت."},{"v":29,"t":"پطرس به وی گفت: «هرگاه همه لغزش خورند، من هرگز نخورم.»"},{"v":30,"t":"عیسی وی را گفت: «هرآینه به تو می‌گویم که امروز در همین شب، قبل از آنکه خروس دومرتبه بانگ زند، تو سه مرتبه مرا انکار خواهی نمود.»"},{"v":31,"t":"لیکن او به تاکید زیادتر می‌گفت: «هرگاه مردنم با تو لازم افتد، تو را هرگز انکار نکنم.» ودیگران نیز همچنان گفتند."},{"v":32,"t":"و چون به موضعی که جتسیمانی نام داشت رسیدند، به شاگردان خود گفت: «در اینجابنشینید تا دعا کنم.»"},{"v":33,"t":"و پطرس و یعقوب ویوحنا را همراه برداشته، مضطرب و دلتنگ گردید"},{"v":34,"t":"و بدیشان گفت: «نفس من از حزن، مشرف بر موت شد. اینجا بمانید و بیدار باشید.»"},{"v":35,"t":"و قدری پیشتر رفته، به روی بر زمین افتاد ودعا کرد تا اگر ممکن باشد آن ساعت از او بگذرد."},{"v":36,"t":"پس گفت: «یا ابا پدر، همه‌چیز نزد تو ممکن است. این پیاله را از من بگذران، لیکن نه به خواهش من بلکه به اراده تو.»"},{"v":37,"t":"پس چون آمد، ایشان را در خواب دیده، پطرس را گفت: «ای شمعون، در خواب هستی؟ آیا نمی توانستی یک ساعت بیدار باشی؟"},{"v":38,"t":"بیدار باشید و دعا کنید تادر آزمایش نیفتید. روح البته راغب است لیکن جسم ناتوان.»"},{"v":39,"t":"و باز رفته، به همان کلام دعانمود."},{"v":40,"t":"و نیز برگشته، ایشان را در خواب یافت زیرا که چشمان ایشان سنگین شده بود وندانستند او را چه جواب دهند."},{"v":41,"t":"و مرتبه سوم آمده، بدیشان گفت: «مابقی را بخوابید واستراحت کنید. کافی است! ساعت رسیده است. اینک پسر انسان به‌دستهای گناهکاران تسلیم می شود."},{"v":42,"t":"برخیزید برویم که اکنون تسلیم‌کننده من نزدیک شد.»"},{"v":43,"t":"در ساعت وقتی که او هنوز سخن می‌گفت، یهودا که یکی از آن دوازده بود، با گروهی بسیار باشمشیرها و چوبها از جانب روسای کهنه و کاتبان و مشایخ آمدند."},{"v":44,"t":"و تسلیم‌کننده او بدیشان نشانی داده، گفته بود: «هر‌که را ببوسم، همان است. او را بگیرید و با حفظ تمام ببرید.»"},{"v":45,"t":"و درساعت نزد وی شده، گفت: «یا سیدی، یا سیدی.» و وی را بوسید."},{"v":46,"t":"ناگاه دستهای خود را بر وی انداخته، گرفتندش."},{"v":47,"t":"و یکی از حاضرین شمشیر خود را کشیده، بر یکی از غلامان رئیس کهنه زده، گوشش را ببرید."},{"v":48,"t":"عیسی روی بدیشان کرده، گفت: «گویا بر دزد با شمشیرها وچوبها بجهت گرفتن من بیرون آمدید!"},{"v":49,"t":"هر روزدر نزد شما در هیکل تعلیم می‌دادم و مرا نگرفتید. لیکن لازم است که کتب تمام گردد.»"},{"v":50,"t":"آنگاه همه او را واگذارده بگریختند."},{"v":51,"t":"و یک جوانی باچادری بر بدن برهنه خود پیچیده، از عقب اوروانه شد. چون جوانان او را گرفتند،"},{"v":52,"t":"چادر راگذارده، برهنه از دست ایشان گریخت."},{"v":53,"t":"و عیسی را نزد رئیس کهنه بردند و جمیع روسای کاهنان و مشایخ و کاتبان بر او جمع گردیدند."},{"v":54,"t":"و پطرس از دور در عقب او می‌آمد تا به خانه رئیس کهنه درآمده، با ملازمان بنشست ونزدیک آتش خود را گرم می‌نمود."},{"v":55,"t":"و روسای کهنه و جمیع اهل شورا در جستجوی شهادت برعیسی بودند تا او را بکشند و هیچ نیافتند،"},{"v":56,"t":"زیراکه هرچند بسیاری بر وی شهادت دروغ می‌دادند، اما شهادت های ایشان موافق نشد."},{"v":57,"t":"وبعضی برخاسته شهادت دروغ داده، گفتند:"},{"v":58,"t":"«ماشنیدیم که او می‌گفت: من این هیکل ساخته شده به‌دست را خراب می‌کنم و در سه روز، دیگری راناساخته شده به‌دست، بنا می‌کنم.»"},{"v":59,"t":"و در این هم باز شهادت های ایشان موافق نشد."},{"v":60,"t":"پس رئیس کهنه از آن میان برخاسته، ازعیسی پرسیده، گفت: «هیچ جواب نمی دهی؟ چه چیز است که اینها در حق تو شهادت می‌دهند؟»"},{"v":61,"t":"اما او ساکت مانده، هیچ جواب نداد. باز رئیس کهنه از او سوال نموده، گفت: «آیا تو مسیح پسرخدای متبارک هستی؟»"},{"v":62,"t":"عیسی گفت: «من هستم؛ و پسر انسان را خواهید دید که برطرف راست قوت نشسته، در ابرهای آسمان می‌آید.»"},{"v":63,"t":"آنگاه رئیس کهنه جامه خود را چاک زده، گفت: «دیگر‌چه حاجت به شاهدان داریم؟"},{"v":64,"t":"کفر او را شنیدید! چه مصلحت می‌دانید؟» پس همه بر او حکم کردند که مستوجب قتل است."},{"v":65,"t":"و بعضی شروع نمودند به آب دهان بروی انداختن و روی او را پوشانیده، او را می‌زدندو می‌گفتند نبوت کن. ملازمان او را می‌زدند."},{"v":66,"t":"و در وقتی که پطرس در ایوان پایین بود، یکی از کنیزان رئیس کهنه آمد"},{"v":67,"t":"و پطرس راچون دید که خود را گرم می‌کند، بر او نگریسته، گفت: «تو نیز با عیسی ناصری می‌بودی؟"},{"v":68,"t":"اوانکار نموده، گفت: «نمی دانم و نمی فهمم که توچه می‌گویی!» و چون بیرون به دهلیز خانه رفت، ناگاه خروس بانگ زد."},{"v":69,"t":"و بار دیگر آن کنیزک اورا دیده، به حاضرین گفتن گرفت که «این شخص از آنها است!»"},{"v":70,"t":"او باز انکار کرد. و بعد از زمانی حاضرین بار دیگر به پطرس گفتند: «در حقیقت تو از آنها می‌باشی زیرا که جلیلی نیز هستی ولهجه تو چنان است.»"},{"v":71,"t":"پس به لعن کردن و قسم خوردن شروع نمود که «آن شخص را که می‌گویید نمی شناسم.»"},{"v":72,"t":"ناگاه خروس مرتبه دیگر بانگ زد. پس پطرس را به‌خاطر آمد آنچه عیسی بدو گفته بود که «قبل از آنکه خروس دومرتبه بانگ زند، سه مرتبه مرا انکار خواهی نمود.» و چون این را به‌خاطر آورد، بگریست."}],"en":[{"v":1,"t":"It was now two days before the Passover and the Feast of Unleavened Bread, and the chief priests and the scribes sought how they might seize him by deception and kill him."},{"v":2,"t":"For they said, “Not during the feast, because there might be a riot among the people.”"},{"v":3,"t":"While he was at Bethany, in the house of Simon the leper, as he sat at the table, a woman came having an alabaster jar of ointment of pure nard—very costly. She broke the jar and poured it over his head."},{"v":4,"t":"But there were some who were indignant among themselves, saying, “Why has this ointment been wasted?"},{"v":5,"t":"For this might have been sold for more than three hundred denarii and given to the poor.” So they grumbled against her."},{"v":6,"t":"But Jesus said, “Leave her alone. Why do you trouble her? She has done a good work for me."},{"v":7,"t":"For you always have the poor with you, and whenever you want to, you can do them good; but you will not always have me."},{"v":8,"t":"She has done what she could. She has anointed my body beforehand for the burying."},{"v":9,"t":"Most certainly I tell you, wherever this Good News may be preached throughout the whole world, that which this woman has done will also be spoken of for a memorial of her.”"},{"v":10,"t":"Judas Iscariot, who was one of the twelve, went away to the chief priests, that he might deliver him to them."},{"v":11,"t":"They, when they heard it, were glad, and promised to give him money. He sought how he might conveniently deliver him."},{"v":12,"t":"On the first day of unleavened bread, when they sacrificed the Passover, his disciples asked him, “Where do you want us to go and prepare that you may eat the Passover?”"},{"v":13,"t":"He sent two of his disciples and said to them, “Go into the city, and there a man carrying a pitcher of water will meet you. Follow him,"},{"v":14,"t":"and wherever he enters in, tell the master of the house, ‘The Teacher says, “Where is the guest room, where I may eat the Passover with my disciples?”’"},{"v":15,"t":"He will himself show you a large upper room furnished and ready. Get ready for us there.”"},{"v":16,"t":"His disciples went out, and came into the city, and found things as he had said to them, and they prepared the Passover."},{"v":17,"t":"When it was evening he came with the twelve."},{"v":18,"t":"As they sat and were eating, Jesus said, “Most certainly I tell you, one of you will betray me—he who eats with me.”"},{"v":19,"t":"They began to be sorrowful, and to ask him one by one, “Surely not I?” And another said, “Surely not I?”"},{"v":20,"t":"He answered them, “It is one of the twelve, he who dips with me in the dish."},{"v":21,"t":"For the Son of Man goes as it is written about him, but woe to that man by whom the Son of Man is betrayed! It would be better for that man if he had not been born.”"},{"v":22,"t":"As they were eating, Jesus took bread, and when he had blessed it, he broke it and gave to them, and said, “Take, eat. This is my body.”"},{"v":23,"t":"He took the cup, and when he had given thanks, he gave to them. They all drank of it."},{"v":24,"t":"He said to them, “This is my blood of the new covenant, which is poured out for many."},{"v":25,"t":"Most certainly I tell you, I will no more drink of the fruit of the vine until that day when I drink it anew in God’s Kingdom.”"},{"v":26,"t":"When they had sung a hymn, they went out to the Mount of Olives."},{"v":27,"t":"Jesus said to them, “All of you will be made to stumble because of me tonight, for it is written, ‘I will strike the shepherd, and the sheep will be scattered.’"},{"v":28,"t":"However, after I am raised up, I will go before you into Galilee.”"},{"v":29,"t":"But Peter said to him, “Although all will be offended, yet I will not.”"},{"v":30,"t":"Jesus said to him, “Most certainly I tell you that you today, even this night, before the rooster crows twice, you will deny me three times.”"},{"v":31,"t":"But he spoke all the more, “If I must die with you, I will not deny you.” They all said the same thing."},{"v":32,"t":"They came to a place which was named Gethsemane. He said to his disciples, “Sit here while I pray.”"},{"v":33,"t":"He took with him Peter, James, and John, and began to be greatly troubled and distressed."},{"v":34,"t":"He said to them, “My soul is exceedingly sorrowful, even to death. Stay here and watch.”"},{"v":35,"t":"He went forward a little, and fell on the ground, and prayed that if it were possible, the hour might pass away from him."},{"v":36,"t":"He said, “Abba, Father, all things are possible to you. Please remove this cup from me. However, not what I desire, but what you desire.”"},{"v":37,"t":"He came and found them sleeping, and said to Peter, “Simon, are you sleeping? Couldn’t you watch one hour?"},{"v":38,"t":"Watch and pray, that you may not enter into temptation. The spirit indeed is willing, but the flesh is weak.”"},{"v":39,"t":"Again he went away and prayed, saying the same words."},{"v":40,"t":"Again he returned and found them sleeping, for their eyes were very heavy; and they didn’t know what to answer him."},{"v":41,"t":"He came the third time and said to them, “Sleep on now, and take your rest. It is enough. The hour has come. Behold, the Son of Man is betrayed into the hands of sinners."},{"v":42,"t":"Arise! Let’s get going. Behold, he who betrays me is at hand.”"},{"v":43,"t":"Immediately, while he was still speaking, Judas, one of the twelve, came—and with him a multitude with swords and clubs, from the chief priests, the scribes, and the elders."},{"v":44,"t":"Now he who betrayed him had given them a sign, saying, “Whomever I will kiss, that is he. Seize him, and lead him away safely.”"},{"v":45,"t":"When he had come, immediately he came to him and said, “Rabbi! Rabbi!” and kissed him."},{"v":46,"t":"They laid their hands on him and seized him."},{"v":47,"t":"But a certain one of those who stood by drew his sword and struck the servant of the high priest, and cut off his ear."},{"v":48,"t":"Jesus answered them, “Have you come out, as against a robber, with swords and clubs to seize me?"},{"v":49,"t":"I was daily with you in the temple teaching, and you didn’t arrest me. But this is so that the Scriptures might be fulfilled.”"},{"v":50,"t":"They all left him, and fled."},{"v":51,"t":"A certain young man followed him, having a linen cloth thrown around himself over his naked body. The young men grabbed him,"},{"v":52,"t":"but he left the linen cloth and fled from them naked."},{"v":53,"t":"They led Jesus away to the high priest. All the chief priests, the elders, and the scribes came together with him."},{"v":54,"t":"Peter had followed him from a distance, until he came into the court of the high priest. He was sitting with the officers, and warming himself in the light of the fire."},{"v":55,"t":"Now the chief priests and the whole council sought witnesses against Jesus to put him to death, and found none."},{"v":56,"t":"For many gave false testimony against him, and their testimony didn’t agree with each other."},{"v":57,"t":"Some stood up and gave false testimony against him, saying,"},{"v":58,"t":"“We heard him say, ‘I will destroy this temple that is made with hands, and in three days I will build another made without hands.’”"},{"v":59,"t":"Even so, their testimony didn’t agree."},{"v":60,"t":"The high priest stood up in the middle, and asked Jesus, “Have you no answer? What is it which these testify against you?”"},{"v":61,"t":"But he stayed quiet, and answered nothing. Again the high priest asked him, “Are you the Christ, the Son of the Blessed?”"},{"v":62,"t":"Jesus said, “I am. You will see the Son of Man sitting at the right hand of Power, and coming with the clouds of the sky.”"},{"v":63,"t":"The high priest tore his clothes and said, “What further need have we of witnesses?"},{"v":64,"t":"You have heard the blasphemy! What do you think?” They all condemned him to be worthy of death."},{"v":65,"t":"Some began to spit on him, and to cover his face, and to beat him with fists, and to tell him, “Prophesy!” The officers struck him with the palms of their hands."},{"v":66,"t":"As Peter was in the courtyard below, one of the maids of the high priest came,"},{"v":67,"t":"and seeing Peter warming himself, she looked at him and said, “You were also with the Nazarene, Jesus!”"},{"v":68,"t":"But he denied it, saying, “I neither know nor understand what you are saying.” He went out on the porch, and the rooster crowed."},{"v":69,"t":"The maid saw him and began again to tell those who stood by, “This is one of them.”"},{"v":70,"t":"But he again denied it. After a little while again those who stood by said to Peter, “You truly are one of them, for you are a Galilean, and your speech shows it.”"},{"v":71,"t":"But he began to curse and to swear, “I don’t know this man of whom you speak!”"},{"v":72,"t":"The rooster crowed the second time. Peter remembered the words that Jesus said to him, “Before the rooster crows twice, you will deny me three times.” When he thought about that, he wept."}],"hr":[{"v":1,"t":"Za dva dana bijaše Pasha i Beskvasni kruhovi. Glavari svećenički i pismoznanci tražili su kako da ga na prijevaru uhvate i ubiju."},{"v":2,"t":"Jer se govorilo: “Nikako ne na Blagdan da ne nastane pobuna naroda.”"},{"v":3,"t":"I kad je u Betaniji, u kući Šimuna Gubavca, bio za stolom, dođe neka žena s alabastrenom posudicom prave skupocjene nardove pomasti. Razbi posudicu i poli ga po glavi."},{"v":4,"t":"A neki negodovahu te će jedan drugomu: “Čemu to rasipanje pomasti?"},{"v":5,"t":"Mogla se pomast prodati za više od tristo denara i dati siromasima.” I otresahu se na nju."},{"v":6,"t":"A Isus reče: “Pustite je, što joj dodijavate? Dobro djelo učini na meni."},{"v":7,"t":"Ta siromaha svagda imate uza se i kad god hoćete možete im dobro činiti, a mene nemate svagda."},{"v":8,"t":"Učinila je što je mogla: unaprijed mi pomaza tijelo za ukop."},{"v":9,"t":"Zaista, kažem vam, gdje se god bude propovijedalo evanđelje, po svem svijetu, navješćivat će se i ovo što ona učini - njoj na spomen.”"},{"v":10,"t":"A Juda Iškariotski, jedan od dvanaestorice, ode glavarima svećeničkim da im ga preda."},{"v":11,"t":"Kad su oni to čuli, obradovali su se i obećali mu dati novca. I tražio je zgodu da ga preda."},{"v":12,"t":"Prvoga dana Beskvasnih kruhova, kad se žrtvovala pasha, upitaju učenici Isusa: “Gdje hoćeš blagovati pashu, da odemo i pripravimo?”"},{"v":13,"t":"On pošalje dvojicu učenika i rekne im: “Idite u grad i namjerit ćete se na čovjeka koji nosi krčag vode. Pođite za njim"},{"v":14,"t":"pa gdje on uđe, recite domaćinu: 'Učitelj pita: Gdje mi je svratište u kojem bih blagovao pashu sa svojim učenicima?'"},{"v":15,"t":"I on će vam pokazati na katu veliko blagovalište, prostrto i spremljeno. Ondje nam pripravite.”"},{"v":16,"t":"Učenici odu, dođu u grad i nađu kako im on reče te priprave pashu."},{"v":17,"t":"A uvečer dođe on s dvanaestoricom."},{"v":18,"t":"I dok bijahu za stolom te blagovahu, reče Isus: “Zaista, kažem vam, jedan će me od vas izdati - koji sa mnom blaguje.”"},{"v":19,"t":"Ožalošćeni, stanu mu govoriti jedan za drugim: “Da nisam ja?”"},{"v":20,"t":"A on im reče: “Jedan od dvanaestorice koji umače sa mnom u zdjelicu."},{"v":21,"t":"Sin Čovječji, istina, odlazi kako je o njemu pisano, ali jao čovjeku onomu koji ga predaje. Tomu bi čovjeku bolje bilo da se ni rodio nije!”"},{"v":22,"t":"I dok su blagovali, on uze kruh, izreče blagoslov pa razlomi, dade im i reče: “Uzmite, ovo je tijelo moje.”"},{"v":23,"t":"I uze čašu, zahvali i dade im. I svi su iz nje pili."},{"v":24,"t":"A on im reče: “Ovo je krv moja, krv Saveza, koja se za mnoge prolijeva."},{"v":25,"t":"Zaista, kažem vam, ne, neću više piti od ovoga roda trsova do onoga dana kad ću ga - novoga - piti u kraljevstvu Božjem.”"},{"v":26,"t":"Otpjevavši hvalospjeve, zaputiše se prema Maslinskoj gori."},{"v":27,"t":"I reče im Isus: “Svi ćete se sablazniti. Ta pisano je: Udarit ću pastira i ovce će se razbjeći."},{"v":28,"t":"Ali kad uskrsnem, ići ću pred vama u Galileju.”"},{"v":29,"t":"Nato će mu Petar: “Ako se i svi sablazne, ja neću!”"},{"v":30,"t":"A Isus mu reče: “Zaista, kažem ti, baš ti, danas, ove noći, prije nego se pijetao dvaput oglasi, triput ćeš me zatajiti.”"},{"v":31,"t":"Ali on je upornije uvjeravao: “Bude li trebalo i umrijeti s tobom - ne, neću te zatajiti.” A tako su svi govorili."},{"v":32,"t":"I dođu u predio imenom Getsemani. I kaže Isus svojim učenicima: “Sjednite ovdje dok se ne pomolim.”"},{"v":33,"t":"I povede sa sobom Petra, Jakova i Ivana. Spopade ga užas i tjeskoba"},{"v":34,"t":"pa im reče: “Duša mi je nasmrt žalosna! Ostanite ovdje i bdijte!”"},{"v":35,"t":"Ode malo dalje i rušeći se na zemlju molio je da ga, ako je moguće, mimoiđe ovaj čas."},{"v":36,"t":"Govoraše: “Abba! Oče! Tebi je sve moguće! Otkloni čašu ovu od mene! Ali ne što ja hoću, nego što hoćeš ti!”"},{"v":37,"t":"I dođe, nađe ih pozaspale pa reče Petru: “Šimune, spavaš? Jedan sat nisi mogao probdjeti?"},{"v":38,"t":"Bdijte i molite da ne padnete u napast. Duh je, istina, voljan, no tijelo je slabo.”"},{"v":39,"t":"Opet ode i pomoli se istim riječima."},{"v":40,"t":"Ponovno dođe i nađe ih pozaspale. Oči im se sklapale i nisu znali što da mu odgovore."},{"v":41,"t":"Dođe i treći put i reče im: “Samo spavajte i počivajte! Gotovo je! Dođe čas! Evo, predaje se Sin Čovječji u ruke grešničke!"},{"v":42,"t":"Ustanite, hajdemo! Evo, izdajica se moj približio!”"},{"v":43,"t":"Uto, dok je on još govorio, stiže Juda, jedan od dvanaestorice, i s njime svjetina s mačevima i toljagama, poslana od glavara svećeničkih, pismoznanaca i starješina."},{"v":44,"t":"A izdajica im njegov dade znak: “Koga poljubim, taj je! Uhvatite ga i oprezno odvedite!”"},{"v":45,"t":"I kako dođe, odmah pristupi k njemu i reče: “Učitelju!” I poljubi ga."},{"v":46,"t":"Oni podignu na nj ruke i uhvate ga."},{"v":47,"t":"A jedan od nazočnih trgnu mač, udari slugu velikoga svećenika i odsiječe mu uho."},{"v":48,"t":"Isus im prozbori: “Kao na razbojnika iziđoste s mačevima i toljagama da me uhvatite."},{"v":49,"t":"Danomice bijah vam u Hramu, naučavah i ne uhvatiste me. No neka se ispune Pisma!”"},{"v":50,"t":"I svi ga ostave i pobjegnu."},{"v":51,"t":"A jedan je mladić išao za njim, ogrnut samo plahtom. I njega htjedoše uhvatiti,"},{"v":52,"t":"no on ostavi plahtu i gol pobježe."},{"v":53,"t":"Zatim odvedoše Isusa velikom svećeniku. I skupe se svi glavari svećenički, starješine i pismoznanci."},{"v":54,"t":"Petar je izdaleka išao za njim do u dvor velikog svećenika. Tu je sjedio sa stražarima i grijao se uz vatru."},{"v":55,"t":"A glavari svećenički i cijelo Vijeće, da bi mogli pogubiti Isusa, tražili su protiv njega kakvo svjedočanstvo, ali nikako da ga nađu."},{"v":56,"t":"Mnogi su doduše lažno svjedočili protiv njega, ali im se svjedočanstva ne slagahu."},{"v":57,"t":"Ustali su neki i lažno svjedočili protiv njega:"},{"v":58,"t":"“Mi smo ga čuli govoriti: 'Ja ću razvaliti ovaj rukotvoreni Hram i za tri dana sagraditi drugi, nerukotvoreni!'”"},{"v":59,"t":"Ali ni u tom im svjedočanstvo ne bijaše složno."},{"v":60,"t":"Usta nato veliki svećenik na sredinu i upita Isusa: “Zar ništa ne odgovaraš? Što to ovi svjedoče protiv tebe?"},{"v":61,"t":"A on je šutio i ništa mu nije odgovarao. Veliki ga svećenik ponovo upita: “Ti li si Krist, Sin Blagoslovljenoga?”"},{"v":62,"t":"A Isus mu reče: “Ja jesam! I gledat ćete Sina Čovječjega gdje sjedi zdesna Sile i dolazi s oblacima nebeskim.”"},{"v":63,"t":"Nato veliki svećenik razdrije haljine i reče: “Što nam još trebaju svjedoci?"},{"v":64,"t":"Čuli ste hulu. Što vam se čini?” Oni svi presudiše da zaslužuje smrt."},{"v":65,"t":"I neki stanu pljuvati po njemu, zastirati mu lice i udarati ga govoreći: “Proreci!” I sluge ga stadoše pljuskati."},{"v":66,"t":"I dok je Petar bio dolje u dvoru, dođe jedna sluškinja velikoga svećenika;"},{"v":67,"t":"ugledavši Petra gdje se grije, upre u nj pogled i reče: “I ti bijaše s Nazarećaninom, Isusom.”"},{"v":68,"t":"On zanijeka: “Niti znam niti razumijem što govoriš.” I iziđe van u predvorje, a pijetao se oglasi."},{"v":69,"t":"Sluškinja ga ugleda i poče opet govoriti nazočnima: “Ovaj je od njih!”"},{"v":70,"t":"On opet nijekaše. Domalo nazočni opet stanu govoriti Petru: “Doista, i ti si od njih! Ta Galilejac si!”"},{"v":71,"t":"On se tada stane kleti i preklinjati: “Ne znam čovjeka o kom govorite!”"},{"v":72,"t":"I odmah se po drugi put oglasi pijetao. I spomenu se Petar one besjede, kako mu ono Isus reče: “Prije nego se pijetao dvaput oglasi, triput ćeš me zatajiti.” I briznu u plač."}]},"15":{"fa":[{"v":1,"t":"بامدادان، بی‌درنگ روسای کهنه بامشایخ و کاتبان و تمام اهل شورامشورت نمودند و عیسی را بند نهاده، بردند و به پیلاطس تسلیم کردند."},{"v":2,"t":"پیلاطس از او پرسید: «آیا تو پادشاه یهودهستی؟» او در جواب وی گفت: «تو می‌گویی.»"},{"v":3,"t":"و چون روسای کهنه ادعای بسیار بر او می نمودند،"},{"v":4,"t":"پیلاطس باز از او سوال کرده، گفت: «هیچ جواب نمی دهی؟ ببین که چقدر بر توشهادت می‌دهند!»"},{"v":5,"t":"اما عیسی باز هیچ جواب نداد، چنانکه پیلاطس متعجب شد."},{"v":6,"t":"و در هر عید یک زندانی، هر‌که رامی خواستند، بجهت ایشان آزاد می‌کرد."},{"v":7,"t":"و برابانامی با شرکای فتنه او که در فتنه خونریزی کرده بودند، در حبس بود."},{"v":8,"t":"آنگاه مردم صدازده، شروع کردند به‌خواستن که برحسب عادت با ایشان عمل نماید."},{"v":9,"t":"پیلاطس درجواب ایشان گفت: «آیا می‌خواهید پادشاه یهود را برای شما آزاد کنم؟»"},{"v":10,"t":"زیرا یافته بودکه روسای کهنه او را از راه حسد تسلیم کرده بودند."},{"v":11,"t":"اما روسای کهنه مردم را تحریض کرده بودند که بلکه برابا را برای ایشان رهاکند."},{"v":12,"t":"پیلاطس باز ایشان را در جواب گفت: «پس چه می‌خواهید بکنم با آن کس که پادشاه یهودش می‌گویید؟»"},{"v":13,"t":"ایشان بار دیگر فریادکردند که «او را مصلوب کن!»"},{"v":14,"t":"پیلاطس بدیشان گفت: «چرا؟ چه بدی کرده است؟» ایشان بیشتر فریاد برآوردند که «او را مصلوب کن.»"},{"v":15,"t":"پس پیلاطس چون خواست که مردم راخشنود گرداند، برابا را برای ایشان آزاد کرد وعیسی را تازیانه زده، تسلیم نمود تا مصلوب شود."},{"v":16,"t":"آنگاه سپاهیان او را به‌سرایی که دارالولایه است برده، تمام فوج را فراهم آوردند"},{"v":17,"t":"وجامه‌ای قرمز بر او پوشانیدند و تاجی از خاربافته، بر سرش گذاردند"},{"v":18,"t":"و او را سلام کردن گرفتند که «سلام‌ای پادشاه یهود!»"},{"v":19,"t":"و نی بر سراو زدند و آب دهان بر وی انداخته و زانو زده، بدو تعظیم می‌نمودند."},{"v":20,"t":"و چون او را استهزاکرده بودند، لباس قرمز را از وی کنده جامه خودش را پوشانیدند و او را بیرون بردند تامصلوبش سازند."},{"v":21,"t":"و راهگذری را شمعون نام، از اهل قیروان که از بلوکات می‌آمد، و پدر اسکندر و رفس بود، مجبور ساختند که صلیب او را بردارد."},{"v":22,"t":"پس اورا به موضعی که جلجتا نام داشت یعنی محل کاسه سر بردند"},{"v":23,"t":"و شراب مخلوط به مر به وی دادند تا بنوشد لیکن قبول نکرد."},{"v":24,"t":"و چون او رامصلوب کردند، لباس او را تقسیم نموده، قرعه برآن افکندند تا هر کس چه برد."},{"v":25,"t":"و ساعت سوم بود که اورا مصلوب کردند."},{"v":26,"t":"و تقصیر نامه وی این نوشته شد: «پادشاه یهود.»"},{"v":27,"t":"و با وی دو دزد را یکی از دست راست و دیگری از دست چپ مصلوب کردند."},{"v":28,"t":"پس تمام گشت آن نوشته‌ای که می‌گوید: «ازخطاکاران محسوب گشت.»"},{"v":29,"t":"و راهگذاران او رادشنام داده و سر خود را جنبانیده، می‌گفتند: «هان‌ای کسی‌که هیکل را خراب می‌کنی و در سه روز آن را بنا می‌کنی،"},{"v":30,"t":"از صلیب به زیرآمده، خود را برهان!»"},{"v":31,"t":"و همچنین روسای کهنه و کاتبان استهزاکنان با یکدیگر می‌گفتند؛ «دیگران را نجات داد و نمی تواند خود را نجات دهد."},{"v":32,"t":"مسیح، پادشاه اسرائیل، الان از صلیب نزول کند تا ببینیم و ایمان آوریم.» و آنانی که با وی مصلوب شدند او را دشنام می‌دادند."},{"v":33,"t":"و چون ساعت ششم رسید تا ساعت نهم تاریکی تمام زمین را فرو گرفت."},{"v":34,"t":"و در ساعت نهم، عیسی به آواز بلند ندا کرده، گفت: «ایلوئی ایلوئی، لما سبقتنی؟» یعنی «الهی الهی چرا مراواگذاردی؟»"},{"v":35,"t":"و بعضی از حاضرین چون شنیدند گفتند: «الیاس را می‌خواند.»"},{"v":36,"t":"پس شخصی دویده، اسفنجی را از سرکه پر کرد و برسر نی نهاده، بدو نوشانید و گفت: «بگذارید ببینیم مگر الیاس بیاید تا او را پایین آورد.»"},{"v":37,"t":"پس عیسی آوازی بلند برآورده، جان بداد."},{"v":38,"t":"آنگاه پرده هیکل از سر تا پا دوپاره شد."},{"v":39,"t":"و چون یوزباشی که مقابل وی ایستاده بود، دید که بدینطور صدا زده، روح را سپرد، گفت؛ «فی الواقع این مرد، پسر خدا بود.»"},{"v":40,"t":"و زنی چند از دور نظر می‌کردند که ازآنجمله مریم مجدلیه بود و مریم مادر یعقوب کوچک و مادر یوشا و سالومه،"},{"v":41,"t":"که هنگام بودن او در جلیل پیروی و خدمت او می‌کردند. و دیگرزنان بسیاری که به اورشلیم آمده بودند."},{"v":42,"t":"و چون شام شد، از آن جهت روز تهیه یعنی روز قبل از سبت بود،"},{"v":43,"t":"یوسف نامی ازاهل رامه که مرد شریف از اعضای شورا و نیزمنتظر ملکوت خدا بود آمد و جرات کرده نزدپیلاطس رفت و جسد عیسی را طلب نمود."},{"v":44,"t":"پیلاطس تعجب کرد که بدین زودی فوت شده باشد، پس یوزباشی را طلبیده، از او پرسید که «آیاچندی گذشته وفات نموده است؟»"},{"v":45,"t":"چون ازیوزباشی دریافت کرد، بدن را به یوسف ارزانی داشت."},{"v":46,"t":"پس کتانی خریده، آن را از صلیب به زیر آورد و به آن کتان کفن کرده، در قبری که ازسنگ تراشیده بود نهاد و سنگی بر سر قبرغلطانید."},{"v":47,"t":"و مریم مجدلیه و مریم مادر یوشادیدند که کجا گذاشته شد."}],"en":[{"v":1,"t":"Immediately in the morning the chief priests, with the elders, scribes, and the whole council, held a consultation, bound Jesus, carried him away, and delivered him up to Pilate."},{"v":2,"t":"Pilate asked him, “Are you the King of the Jews?” He answered, “So you say.”"},{"v":3,"t":"The chief priests accused him of many things."},{"v":4,"t":"Pilate again asked him, “Have you no answer? See how many things they testify against you!”"},{"v":5,"t":"But Jesus made no further answer, so that Pilate marveled."},{"v":6,"t":"Now at the feast he used to release to them one prisoner, whomever they asked of him."},{"v":7,"t":"There was one called Barabbas, bound with his fellow insurgents, men who in the insurrection had committed murder."},{"v":8,"t":"The multitude, crying aloud, began to ask him to do as he always did for them."},{"v":9,"t":"Pilate answered them, saying, “Do you want me to release to you the King of the Jews?”"},{"v":10,"t":"For he perceived that for envy the chief priests had delivered him up."},{"v":11,"t":"But the chief priests stirred up the multitude, that he should release Barabbas to them instead."},{"v":12,"t":"Pilate again asked them, “What then should I do to him whom you call the King of the Jews?”"},{"v":13,"t":"They cried out again, “Crucify him!”"},{"v":14,"t":"Pilate said to them, “Why, what evil has he done?” But they cried out exceedingly, “Crucify him!”"},{"v":15,"t":"Pilate, wishing to please the multitude, released Barabbas to them, and handed over Jesus, when he had flogged him, to be crucified."},{"v":16,"t":"The soldiers led him away within the court, which is the Praetorium; and they called together the whole cohort."},{"v":17,"t":"They clothed him with purple; and weaving a crown of thorns, they put it on him."},{"v":18,"t":"They began to salute him, “Hail, King of the Jews!”"},{"v":19,"t":"They struck his head with a reed and spat on him, and bowing their knees, did homage to him."},{"v":20,"t":"When they had mocked him, they took the purple cloak off him, and put his own garments on him. They led him out to crucify him."},{"v":21,"t":"They compelled one passing by, coming from the country, Simon of Cyrene, the father of Alexander and Rufus, to go with them that he might bear his cross."},{"v":22,"t":"They brought him to the place called Golgotha, which is, being interpreted, “The place of a skull.”"},{"v":23,"t":"They offered him wine mixed with myrrh to drink, but he didn’t take it."},{"v":24,"t":"Crucifying him, they parted his garments among them, casting lots on them, what each should take."},{"v":25,"t":"It was the third hour when they crucified him."},{"v":26,"t":"The superscription of his accusation was written over him: “THE KING OF THE JEWS.”"},{"v":27,"t":"With him they crucified two robbers, one on his right hand, and one on his left."},{"v":28,"t":"The Scripture was fulfilled which says, “He was counted with transgressors.”"},{"v":29,"t":"Those who passed by blasphemed him, wagging their heads and saying, “Ha! You who destroy the temple and build it in three days,"},{"v":30,"t":"save yourself, and come down from the cross!”"},{"v":31,"t":"Likewise, also the chief priests mocking among themselves with the scribes said, “He saved others. He can’t save himself."},{"v":32,"t":"Let the Christ, the King of Israel, now come down from the cross, that we may see and believe him.” Those who were crucified with him also insulted him."},{"v":33,"t":"When the sixth hour had come, there was darkness over the whole land until the ninth hour."},{"v":34,"t":"At the ninth hour Jesus cried with a loud voice, saying, “Eloi, Eloi, lama sabachthani?” which is, being interpreted, “My God, my God, why have you forsaken me?”"},{"v":35,"t":"Some of those who stood by, when they heard it, said, “Behold, he is calling Elijah.”"},{"v":36,"t":"One ran, and filling a sponge full of vinegar, put it on a reed and gave it to him to drink, saying, “Let him be. Let’s see whether Elijah comes to take him down.”"},{"v":37,"t":"Jesus cried out with a loud voice, and gave up the spirit."},{"v":38,"t":"The veil of the temple was torn in two from the top to the bottom."},{"v":39,"t":"When the centurion, who stood by opposite him, saw that he cried out like this and breathed his last, he said, “Truly this man was the Son of God!”"},{"v":40,"t":"There were also women watching from afar, among whom were both Mary Magdalene and Mary the mother of James the less and of Joses, and Salome;"},{"v":41,"t":"who, when he was in Galilee, followed him and served him; and many other women who came up with him to Jerusalem."},{"v":42,"t":"When evening had now come, because it was the Preparation Day, that is, the day before the Sabbath,"},{"v":43,"t":"Joseph of Arimathaea, a prominent council member who also himself was looking for God’s Kingdom, came. He boldly went in to Pilate, and asked for Jesus’ body."},{"v":44,"t":"Pilate was surprised to hear that he was already dead; and summoning the centurion, he asked him whether he had been dead long."},{"v":45,"t":"When he found out from the centurion, he granted the body to Joseph."},{"v":46,"t":"He bought a linen cloth, and taking him down, wound him in the linen cloth and laid him in a tomb which had been cut out of a rock. He rolled a stone against the door of the tomb."},{"v":47,"t":"Mary Magdalene and Mary the mother of Joses, saw where he was laid."}],"hr":[{"v":1,"t":"Odmah izjutra glavari svećenički zajedno sa starješinama i pismoznancima - cijelo Vijeće - upriličili su vijećanje pa Isusa svezali, odveli i predali Pilatu."},{"v":2,"t":"I upita ga Pilat: “Ti li si kralj židovski?” On mu odgovori: “Ti kažeš.”"},{"v":3,"t":"I glavari ga svećenički teško optuživahu."},{"v":4,"t":"Pilat ga opet upita: “Ništa ne odgovaraš? Gle, koliko te optužuju.”"},{"v":5,"t":"A Isus ništa više ne odgovori te se Pilat čudio."},{"v":6,"t":"O Blagdanu bi im pustio uznika koga bi zaiskali."},{"v":7,"t":"A zajedno s pobunjenicima koji u pobuni počiniše umorstvo bijaše u okove bačen čovjek zvani Baraba."},{"v":8,"t":"I uziđe svjetina te poče od Pilata iskati ono što im običavaše činiti."},{"v":9,"t":"A on im odgovori: “Hoćete li da vam pustim kralja židovskoga?”"},{"v":10,"t":"Znao je doista da ga glavari svećenički bijahu predali iz zavisti."},{"v":11,"t":"Ali glavari svećenički podjare svjetinu da traži neka im radije pusti Barabu."},{"v":12,"t":"Pilat ih opet upita: “Što dakle da učinim s ovim kojega zovete kraljem židovskim?”"},{"v":13,"t":"A oni opet povikaše: “Raspni ga!”"},{"v":14,"t":"Reče im Pilat: “Ta što je zla učinio?” Povikaše još jače: “Raspni ga!”"},{"v":15,"t":"Hoteći ugoditi svjetini, Pilat im pusti Barabu, a Isusa izbičeva i preda da se razapne."},{"v":16,"t":"Vojnici ga odvedu u unutarnjost dvora, to jest u pretorij, pa sazovu cijelu četu"},{"v":17,"t":"i zaogrnu ga grimizom; spletu trnov vijenac i stave mu na glavu"},{"v":18,"t":"te ga stanu pozdravljati: “Zdravo, kralju židovski!”"},{"v":19,"t":"I udarahu ga trskom po glavi, pljuvahu po njemu i klanjahu mu se prigibajući koljena."},{"v":20,"t":"A pošto ga izrugaše, svukoše mu grimiz i obukoše mu njegove haljine. I izvedu ga da ga razapnu."},{"v":21,"t":"I prisile nekog prolaznika koji je dolazio s polja, Šimuna Cirenca, oca Aleksandrova i Rufova, da mu ponese križ."},{"v":22,"t":"I dovuku ga na mjesto Golgotu, što znači Lubanjsko mjesto."},{"v":23,"t":"I nuđahu mu piti namirisana vina, ali on ne uze."},{"v":24,"t":"Kad ga razapeše, razdijele među se haljine njegove bacivši za njih kocku - što će tko uzeti."},{"v":25,"t":"A bijaše treća ura kad ga razapeše."},{"v":26,"t":"Bijaše napisan i natpis o njegovoj krivici: “Kralj židovski.”"},{"v":27,"t":"A zajedno s njime razapnu i dva razbojnika, jednoga njemu zdesna, drugoga slijeva."},{"v":28,"t":"#"},{"v":29,"t":"Prolaznici su ga pogrđivali mašući glavama: “Ej, ti, koji razvaljuješ Hram i sagradiš ga za tri dana,"},{"v":30,"t":"spasi sam sebe, siđi s križa!”"},{"v":31,"t":"Slično i glavari svećenički s pismoznancima rugajući se govorahu jedni drugima: “Druge je spasio, sebe ne može spasiti!"},{"v":32,"t":"Krist, kralj Izraelov! Neka sad siđe s križa da vidimo i povjerujemo!” Vrijeđahu ga i oni koji bijahu s njim raspeti."},{"v":33,"t":"A o šestoj uri tama nasta po svoj zemlji - sve do ure devete."},{"v":34,"t":"O devetoj uri povika Isus iza glasa: “Eloi, Eloi lama sabahtani?” To znači: “Bože moj, Bože moj, zašto si me ostavio?”"},{"v":35,"t":"Neki od nazočnih čuvši to govorahu: “Gle, Iliju zove.”"},{"v":36,"t":"A jedan otrča, natopi spužvu octom, natakne na trsku i pruži mu piti govoreći: “Pustite da vidimo hoće li doći Ilija da ga skine.”"},{"v":37,"t":"A Isus zavapi jakim glasom i izdahnu."},{"v":38,"t":"I zavjesa se hramska razdrije nadvoje, odozgor dodolje."},{"v":39,"t":"A kad satnik koji stajaše njemu nasuprot vidje da tako izdahnu, reče: “Zaista, ovaj čovjek bijaše Sin Božji!”"},{"v":40,"t":"Izdaleka promatrahu i neke žene: među njima Marija Magdalena i Marija, majka Jakova Mlađega i Josipa, i Saloma -"},{"v":41,"t":"te su ga pratile kad bijaše u Galileji i posluživale mu - i mnoge druge koje uziđoše s njim u Jeruzalem."},{"v":42,"t":"A uvečer, budući da je bila Priprava, to jest predvečerje subote,"},{"v":43,"t":"dođe Josip iz Arimateje, ugledan vijećnik, koji također isčekivaše kraljevstvo Božje: odvaži se, uđe k Pilatu i zaiska tijelo Isusovo."},{"v":44,"t":"Pilat se začudi da je već umro pa dozva satnika i upita ga je li odavna umro."},{"v":45,"t":"Kad sazna od satnika, darova Josipu tijelo."},{"v":46,"t":"Josip kupi platno, skine tijelo i zavije ga u platno te položi u grob, koji bijaše izduben iz stijene. I dokotrlja kamen na grobna vrata."},{"v":47,"t":"A Marija Magdalena i Marija Josipova promatrahu kamo ga polažu."}]},"16":{"fa":[{"v":1,"t":"پس چون سبت گذشته بود، مریم مجدلیه و مریم مادر یعقوب و سالومه حنوط خریده، آمدند تا او را تدهین کنند."},{"v":2,"t":"وصبح روز یکشنبه را بسیار زود وقت طلوع آفتاب بر سر قبر‌آمدند."},{"v":3,"t":"و با یکدیگر می‌گفتند: «کیست که سنگ را برای ما از سر قبر بغلطاند؟»"},{"v":4,"t":"چون نگریستند، دیدند که سنگ غلطانیده شده است زیرا بسیار بزرگ بود."},{"v":5,"t":"و چون به قبر درآمدند، جوانی را که جامه‌ای سفید دربرداشت بر جانب راست نشسته دیدند. پس متحیر شدند."},{"v":6,"t":"اوبدیشان گفت: «ترسان مباشید! عیسی ناصری مصلوب را می‌طلبید؟ او برخاسته است! در اینجانیست. آن موضعی را که او را نهاده بودند، ملاحظه کنید."},{"v":7,"t":"لیکن رفته، شاگردان او و پطرس را اطلاع دهید که پیش از شما به جلیل می‌رود. اورا در آنجا خواهید دید، چنانکه به شما فرموده بود.»"},{"v":8,"t":"پس بزودی بیرون شده از قبر گریختندزیرا لرزه و حیرت ایشان را فرو گرفته بود و به کسی هیچ نگفتند زیرا می‌ترسیدند."},{"v":9,"t":"و صبحگاهان، روز اول هفته چون برخاسته بود، نخستین به مریم مجدلیه که از او هفت دیوبیرون کرده بود ظاهر شد."},{"v":10,"t":"و او رفته اصحاب اورا که گریه و ماتم می‌کردند خبر داد."},{"v":11,"t":"و ایشان چون شنیدند که زنده گشته و بدو ظاهر شده بود، باور نکردند."},{"v":12,"t":"و بعد از آن به صورت دیگر به دو نفر ازایشان در هنگامی که به دهات می‌رفتند، هویداگردید."},{"v":13,"t":"ایشان رفته، دیگران را خبر دادند، لیکن ایشان را نیز تصدیق ننمودند."},{"v":14,"t":"و بعد از آن بدان یازده هنگامی که به غذانشسته بودند ظاهر شد و ایشان را به‌سبب بی‌ایمانی و سخت دلی ایشان توبیخ نمود زیرا به آنانی که او را برخاسته دیده بودند، تصدیق ننمودند."},{"v":15,"t":"پس بدیشان گفت: «در تمام عالم بروید وجمیع خلایق را به انجیل موعظه کنید."},{"v":16,"t":"هر‌که ایمان آورده، تعمید یابد نجات یابد و اما هر‌که ایمان نیاورد بر او حکم خواهد شد."},{"v":17,"t":"و این آیات همراه ایمانداران خواهد بود که به نام من دیوها را بیرون کنند و به زبانهای تازه حرف زنند"},{"v":18,"t":"و مارها را بردارند و اگر زهر قاتلی بخورندضرری بدیشان نرساند و هرگاه دستها بر مریضان گذارند شفا خواهند یافت.»"},{"v":19,"t":"و خداوند بعد از آنکه به ایشان سخن گفته بود، به سوی آسمان مرتفع شده، به‌دست راست خدا بنشست."},{"v":20,"t":"و ایشان بیرون رفته، در هر جاموعظه می‌کردند و خداوند با ایشان کار می‌کرد وبه آیاتی که همراه ایشان می‌بود، کلام را ثابت می‌گردانید."}],"en":[{"v":1,"t":"When the Sabbath was past, Mary Magdalene, and Mary the mother of James, and Salome bought spices, that they might come and anoint him."},{"v":2,"t":"Very early on the first day of the week, they came to the tomb when the sun had risen."},{"v":3,"t":"They were saying among themselves, “Who will roll away the stone from the door of the tomb for us?”"},{"v":4,"t":"for it was very big. Looking up, they saw that the stone was rolled back."},{"v":5,"t":"Entering into the tomb, they saw a young man sitting on the right side, dressed in a white robe; and they were amazed."},{"v":6,"t":"He said to them, “Don’t be amazed. You seek Jesus, the Nazarene, who has been crucified. He has risen! He is not here. See the place where they laid him!"},{"v":7,"t":"But go, tell his disciples and Peter, ‘He goes before you into Galilee. There you will see him, as he said to you.’”"},{"v":8,"t":"They went out, and fled from the tomb, for trembling and astonishment had come on them. They said nothing to anyone; for they were afraid."},{"v":9,"t":"Now when he had risen early on the first day of the week, he appeared first to Mary Magdalene, from whom he had cast out seven demons."},{"v":10,"t":"She went and told those who had been with him, as they mourned and wept."},{"v":11,"t":"When they heard that he was alive and had been seen by her, they disbelieved."},{"v":12,"t":"After these things he was revealed in another form to two of them as they walked, on their way into the country."},{"v":13,"t":"They went away and told it to the rest. They didn’t believe them, either."},{"v":14,"t":"Afterward he was revealed to the eleven themselves as they sat at the table; and he rebuked them for their unbelief and hardness of heart, because they didn’t believe those who had seen him after he had risen."},{"v":15,"t":"He said to them, “Go into all the world and preach the Good News to the whole creation."},{"v":16,"t":"He who believes and is baptized will be saved; but he who disbelieves will be condemned."},{"v":17,"t":"These signs will accompany those who believe: in my name they will cast out demons; they will speak with new languages;"},{"v":18,"t":"they will take up serpents; and if they drink any deadly thing, it will in no way hurt them; they will lay hands on the sick, and they will recover.”"},{"v":19,"t":"So then the Lord, after he had spoken to them, was received up into heaven and sat down at the right hand of God."},{"v":20,"t":"They went out and preached everywhere, the Lord working with them and confirming the word by the signs that followed. Amen."}],"hr":[{"v":1,"t":"Kad prođe subota, Marija Magdalena i Marija Jakovljeva i Saloma kupiše miomirisa da odu pomazati Isusa."},{"v":2,"t":"I prvoga dana u tjednu, veoma rano, o izlasku sunčevu, dođu na grob."},{"v":3,"t":"I razgovarahu među sobom: “Tko će nam otkotrljati kamen s vrata grobnih?”"},{"v":4,"t":"Pogledaju, a ono kamen otkotrljan. Bijaše doista veoma velik."},{"v":5,"t":"I ušavši u grob, ugledaju mladića zaogrnuta bijelom haljinom gdje sjedi zdesna. I preplaše se."},{"v":6,"t":"A on će im: “Ne plašite se! Isusa tražite, Nazarećanina, Raspetoga? Uskrsnu! Nije ovdje! Evo mjesta kamo ga položiše."},{"v":7,"t":"Nego idite, recite njegovim učenicima i Petru: Ide pred vama u Galileju! Ondje ćete ga vidjeti, kamo vam reče!”"},{"v":8,"t":"One iziđu i stanu bježati od groba: spopade ih strah i trepet. I nikomu ništa ne rekoše jer se bojahu."},{"v":9,"t":"Uskrsnuvši dakle rano prvog dana u tjednu, ukaza se najprije Mariji Magdaleni iz koje bijaše istjerao sedam zloduha."},{"v":10,"t":"Ona ode i dojavi njegovima, tužnima i zaplakanima."},{"v":11,"t":"Kad su oni čuli da je živ i da ga je ona vidjela, ne povjerovaše."},{"v":12,"t":"Nakon toga ukazao se u drugome obličju dvojici od njih na putu dok su išli u selo."},{"v":13,"t":"I oni odu i dojave drugima. Ni njima ne povjerovaše."},{"v":14,"t":"Napokon se ukaza jedanaestorici dok bijahu za stolom. Prekori njihovu nevjeru i okorjelost srca što ne povjerovaše onima koji ga vidješe uskrsla od mrtvih."},{"v":15,"t":"I reče im: “Pođite po svem svijetu, propovijedajte evanđelje svemu stvorenju."},{"v":16,"t":"Tko uzvjeruje i pokrsti se, spasit će se, a tko ne uzvjeruje, osudit će se."},{"v":17,"t":"A ovi će znakovi pratiti one koji uzvjeruju: u ime će moje izganjati zloduhe, novim će jezicima zboriti,"},{"v":18,"t":"zmije uzimati; i popiju li što smrtonosno, ne, neće im nauditi; na nemoćnike će ruke polagati, i bit će im dobro.”"},{"v":19,"t":"I Gospodin Isus, pošto im to reče, bude uzet na nebo i sjede zdesna Bogu."},{"v":20,"t":"Oni pak odoše i propovijedahu posvuda, a Gospodin surađivaše i utvrđivaše Riječ popratnim znakovima."}]}},"LUK":{"1":{"fa":[{"v":1,"t":"از آنجهت که بسیاری دست خود را درازکردند به سوی تالیف حکایت آن اموری که نزد ما به اتمام رسید،"},{"v":2,"t":"چنانچه آنانی که از ابتدانظارگان و خادمان کلام بودند به ما رسانیدند،"},{"v":3,"t":"من نیز مصلحت چنان دیدم که همه را من البدایه به تدقیق در‌پی رفته، به ترتیب به تو بنویسم‌ای تیوفلس عزیز،"},{"v":4,"t":"تا صحت آن کلامی که در آن تعلیم یافته‌ای دریابی."},{"v":5,"t":"در ایام هیرودیس پادشاه یهودیه، کاهنی زکریا نام از فرقه ابیا بود که زن او از دختران هارون بود و الیصابات نام داشت."},{"v":6,"t":"و هر دو در حضورخدا صالح و به جمیع احکام و فرایض خداوند، بی‌عیب سالک بودند."},{"v":7,"t":"و ایشان را فرزندی نبودزیرا که الیصابات نازاد بود و هر دو دیرینه سال بودند."},{"v":8,"t":"و واقع شد که چون به نوبت فرقه خود درحضور خدا کهانت می‌کرد،"},{"v":9,"t":"حسب عادت کهانت، نوبت او شد که به قدس خداوند درآمده، بخور بسوزاند."},{"v":10,"t":"و در وقت بخور، تمام جماعت قوم بیرون عبادت می‌کردند."},{"v":11,"t":"ناگاه فرشته خداوند به طرف راست مذبح بخور ایستاده، بر وی ظاهر گشت."},{"v":12,"t":"چون زکریااو را دید، در حیرت افتاده، ترس بر او مستولی شد."},{"v":13,"t":"فرشته بدو گفت: «ای زکریا ترسان مباش، زیرا که دعای تو مستجاب گردیده است وزوجه ات الیصابات برای تو پسری خواهد زاییدو او را یحیی خواهی نامید."},{"v":14,"t":"و تو را خوشی وشادی رخ خواهد نمود و بسیاری از ولادت اومسرور خواهند شد."},{"v":15,"t":"زیرا که در حضورخداوند بزرگ خواهد بود و شراب و مسکری نخواهد نوشید و از شکم مادر خود، پر ازروح‌القدس خواهد بود."},{"v":16,"t":"و بسیاری ازبنی‌اسرائیل را، به سوی خداوند خدای ایشان خواهد برگردانید."},{"v":17,"t":"و او به روح و قوت الیاس پیش روی وی خواهد خرامید، تا دلهای پدران رابه طرف پسران و نافرمانان را به حکمت عادلان بگرداند تا قومی مستعد برای خدا مهیا سازد.»"},{"v":18,"t":"زکریا به فرشته گفت: «این را چگونه بدانم وحال آنکه من پیر هستم و زوجه‌ام دیرینه سال است؟»"},{"v":19,"t":"فرشته در جواب وی گفت: «من جبرائیل هستم که در حضور خدا می‌ایستم وفرستاده شدم تا به تو سخن گویم و از این امور تورا مژده دهم."},{"v":20,"t":"و الحال تا این امور واقع نگردد، گنگ شده یارای حرف زدن نخواهی داشت، زیراسخن های مرا که در وقت خود به وقوع خواهدپیوست، باور نکردی.»"},{"v":21,"t":"و جماعت منتظر زکریامی بودند و از طول توقف او در قدس متعجب شدند."},{"v":22,"t":"اما چون بیرون آمده نتوانست با ایشان حرف زند، پس فهمیدند که در قدس رویایی دیده است، پس به سوی ایشان اشاره می‌کرد و ساکت ماند."},{"v":23,"t":"و چون ایام خدمت او به اتمام رسید، به خانه خود رفت."},{"v":24,"t":"و بعد از آن روزها، زن او الیصابات حامله شده، مدت پنج ماه خود را پنهان نمود و گفت:"},{"v":25,"t":"«به اینطور خداوند به من عمل نمود درروزهایی که مرا منظور داشت، تا ننگ مرا از نظرمردم بردارد.»"},{"v":26,"t":"و در ماه ششم جبرائیل فرشته از جانب خدا به بلدی از جلیل که ناصره نام داشت، فرستاده شد."},{"v":27,"t":"نزد باکره‌ای نامزد مردی مسمی به یوسف از خاندان داود و نام آن باکره مریم بود."},{"v":28,"t":"پس فرشته نزد او داخل شده، گفت: «سلام برتو‌ای نعمت رسیده، خداوند با توست و تو درمیان زنان مبارک هستی.»"},{"v":29,"t":"چون او را دید، ازسخن او مضطرب شده، متفکر شد که این چه نوع تحیت است."},{"v":30,"t":"فرشته بدو گفت: «ای مریم ترسان مباش زیرا که نزد خدا نعمت یافته‌ای."},{"v":31,"t":"واینک حامله شده، پسری خواهی زایید و او راعیسی خواهی نامید."},{"v":32,"t":"او بزرگ خواهد بود و به پسر حضرت اعلی، مسمی شود، و خداوند خداتخت پدرش داود را بدو عطا خواهد فرمود."},{"v":33,"t":"واو بر خاندان یعقوب تا به ابد پادشاهی خواهد کردو سلطنت او را نهایت نخواهد بود.»"},{"v":34,"t":"مریم به فرشته گفت: «این چگونه می‌شود وحال آنکه مردی را نشناخته‌ام؟»"},{"v":35,"t":"فرشته درجواب وی گفت: «روح‌القدس بر تو خواهد آمد وقوت حضرت اعلی بر تو سایه خواهد افکند، از آنجهت آن مولود مقدس، پسر خدا خوانده خواهد شد."},{"v":36,"t":"و اینک الیصابات از خویشان تونیز در‌پیری به پسری حامله شده و این ماه ششم است، مر او را که نازاد می‌خواندند."},{"v":37,"t":"زیرا نزدخدا هیچ امری محال نیست.»"},{"v":38,"t":"مریم گفت: «اینک کنیز خداوندم. مرا برحسب سخن تو واقع شود.» پس فرشته از نزد او رفت."},{"v":39,"t":"در آن روزها، مریم برخاست و به بلدی ازکوهستان یهودیه بشتاب رفت."},{"v":40,"t":"و به خانه زکریادرآمده، به الیصابات سلام کرد."},{"v":41,"t":"و چون الیصابات سلام مریم را شنید، بچه در رحم او به حرکت آمد و الیصابات به روح‌القدس پر شده،"},{"v":42,"t":"به آواز بلند صدا زده گفت: «تو در میان زنان مبارک هستی و مبارک است ثمره رحم تو."},{"v":43,"t":"و ازکجا این به من رسید که مادر خداوند من، به نزد من آید؟"},{"v":44,"t":"زیرا اینک چون آواز سلام تو گوش زدمن شد، بچه از خوشی در رحم من به حرکت آمد."},{"v":45,"t":"و خوشابحال او که ایمان آورد، زیرا که آنچه از جانب خداوند به وی گفته شد، به انجام خواهدرسید.»"},{"v":46,"t":"پس مریم گفت: «جان من خداوند راتمجید می‌کند،"},{"v":47,"t":"و روح من به رهاننده من خدابوجد آمد،"},{"v":48,"t":"زیرا بر‌حقارت کنیز خود نظرافکند. زیرا هان از کنون تمامی طبقات مراخوشحال خواهند خواند،"},{"v":49,"t":"زیرا آن قادر، به من کارهای عظیم کرده و نام او قدوس است،"},{"v":50,"t":"ورحمت او نسلا بعد نسل است. بر آنانی که از او می ترسند."},{"v":51,"t":"به بازوی خود، قدرت را ظاهرفرمود و متکبران را به خیال دل ایشان پراکنده ساخت."},{"v":52,"t":"جباران را از تختها به زیر افکند. وفروتنان را سرافراز گردانید."},{"v":53,"t":"گرسنگان را به چیزهای نیکو سیر فرمود و دولتمندان راتهیدست رد نمود."},{"v":54,"t":"بنده خود اسرائیل را یاری کرد، به یادگاری رحمانیت خویش،"},{"v":55,"t":"چنانکه به اجداد ما گفته بود، به ابراهیم و به ذریت او تاابدالاباد.»"},{"v":56,"t":"و مریم قریب به سه ماه نزد وی ماند. پس به خانه خود مراجعت کرد."},{"v":57,"t":"اما چون الیصابات را وقت وضع حمل رسید، پسری بزاد."},{"v":58,"t":"و همسایگان و خویشان اوچون شنیدند که خداوند رحمت عظیمی بر وی کرده، با او شادی کردند."},{"v":59,"t":"و واقع شد در روزهشتم چون برای ختنه طفل آمدند، که نام پدرش زکریا را بر او می‌نهادند."},{"v":60,"t":"اما مادرش ملتفت شده، گفت: «نی بلکه به یحیی نامیده می‌شود.»"},{"v":61,"t":"به وی گفتند: «از قبیله تو هیچ‌کس این اسم راندارد.»"},{"v":62,"t":"پس به پدرش اشاره کردند که «او را چه نام خواهی نهاد؟»"},{"v":63,"t":"او تخته‌ای خواسته بنوشت که «نام او یحیی است» و همه متعجب شدند."},{"v":64,"t":"در ساعت، دهان و زبان او باز گشته، به حمدخدا متکلم شد."},{"v":65,"t":"پس بر تمامی همسایگان ایشان، خوف مستولی گشت و جمیع این وقایع در همه کوهستان یهودیه شهرت یافت."},{"v":66,"t":"و هرکه شنید، در خاطر خود تفکر نموده، گفت: «این چه نوع طفل خواهد بود؟» و دست خداوند با وی می بود."},{"v":67,"t":"و پدرش زکریا از روح‌القدس پر شده نبوت نموده، گفت:"},{"v":68,"t":"«خداوند خدای اسرائیل متبارک باد، زیرا از قوم خود تفقد نموده، برای ایشان فدایی قرار داد."},{"v":69,"t":"و شاخ نجاتی برای مابرافراشت، در خانه بنده خود داود."},{"v":70,"t":"چنانچه به زبان مقدسین گفت که از بدو عالم انبیای اومی بودند،"},{"v":71,"t":"رهایی از دشمنان ما و از دست آنانی که از ما نفرت دارند،"},{"v":72,"t":"تا رحمت را برپدران ما به‌جا آرد و عهد مقدس خود را تذکرفرماید."},{"v":73,"t":"سوگندی که برای پدر ما ابراهیم یادکرد،"},{"v":74,"t":"که ما را فیض عطا فرماید، تا از دست دشمنان خود رهایی یافته، او را بی‌خوف عبادت کنیم."},{"v":75,"t":"در حضور او به قدوسیت و عدالت، درتمامی روزهای عمر خود."},{"v":76,"t":"و تو‌ای طفل نبی حضرت اعلی خوانده خواهی شد، زیرا پیش روی خداوند خواهی خرامید، تا طرق او را مهیاسازی،"},{"v":77,"t":"تا قوم او را معرفت نجات دهی، درآمرزش گناهان ایشان."},{"v":78,"t":"به احشای رحمت خدای ما که به آن سپیده از عالم اعلی از ما تفقدنمود،"},{"v":79,"t":"تا ساکنان در ظلمت و ظل موت را نوردهد. و پایهای ما را به طریق سلامتی هدایت نماید.»"},{"v":80,"t":"پس طفل نمو کرده، در روح قوی می‌گشت. و تا روز ظهور خود برای اسرائیل، دربیابان بسر می‌برد."}],"en":[{"v":1,"t":"Since many have undertaken to set in order a narrative concerning those matters which have been fulfilled among us,"},{"v":2,"t":"even as those who from the beginning were eyewitnesses and servants of the word delivered them to us,"},{"v":3,"t":"it seemed good to me also, having traced the course of all things accurately from the first, to write to you in order, most excellent Theophilus;"},{"v":4,"t":"that you might know the certainty concerning the things in which you were instructed."},{"v":5,"t":"There was in the days of Herod, the king of Judea, a certain priest named Zacharias, of the priestly division of Abijah. He had a wife of the daughters of Aaron, and her name was Elizabeth."},{"v":6,"t":"They were both righteous before God, walking blamelessly in all the commandments and ordinances of the Lord."},{"v":7,"t":"But they had no child, because Elizabeth was barren, and they both were well advanced in years."},{"v":8,"t":"Now while he executed the priest’s office before God in the order of his division"},{"v":9,"t":"according to the custom of the priest’s office, his lot was to enter into the temple of the Lord and burn incense."},{"v":10,"t":"The whole multitude of the people were praying outside at the hour of incense."},{"v":11,"t":"An angel of the Lord appeared to him, standing on the right side of the altar of incense."},{"v":12,"t":"Zacharias was troubled when he saw him, and fear fell upon him."},{"v":13,"t":"But the angel said to him, “Don’t be afraid, Zacharias, because your request has been heard. Your wife, Elizabeth, will bear you a son, and you shall call his name John."},{"v":14,"t":"You will have joy and gladness, and many will rejoice at his birth."},{"v":15,"t":"For he will be great in the sight of the Lord, and he will drink no wine nor strong drink. He will be filled with the Holy Spirit, even from his mother’s womb."},{"v":16,"t":"He will turn many of the children of Israel to the Lord their God."},{"v":17,"t":"He will go before him in the spirit and power of Elijah, ‘to turn the hearts of the fathers to the children,’ and the disobedient to the wisdom of the just; to prepare a people prepared for the Lord.”"},{"v":18,"t":"Zacharias said to the angel, “How can I be sure of this? For I am an old man, and my wife is well advanced in years.”"},{"v":19,"t":"The angel answered him, “I am Gabriel, who stands in the presence of God. I was sent to speak to you and to bring you this good news."},{"v":20,"t":"Behold, you will be silent and not able to speak until the day that these things will happen, because you didn’t believe my words, which will be fulfilled in their proper time.”"},{"v":21,"t":"The people were waiting for Zacharias, and they marveled that he delayed in the temple."},{"v":22,"t":"When he came out, he could not speak to them. They perceived that he had seen a vision in the temple. He continued making signs to them, and remained mute."},{"v":23,"t":"When the days of his service were fulfilled, he departed to his house."},{"v":24,"t":"After these days Elizabeth his wife conceived, and she hid herself five months, saying,"},{"v":25,"t":"“Thus has the Lord done to me in the days in which he looked at me, to take away my reproach among men.”"},{"v":26,"t":"Now in the sixth month, the angel Gabriel was sent from God to a city of Galilee named Nazareth,"},{"v":27,"t":"to a virgin pledged to be married to a man whose name was Joseph, of David’s house. The virgin’s name was Mary."},{"v":28,"t":"Having come in, the angel said to her, “Rejoice, you highly favored one! The Lord is with you. Blessed are you among women!”"},{"v":29,"t":"But when she saw him, she was greatly troubled at the saying, and considered what kind of salutation this might be."},{"v":30,"t":"The angel said to her, “Don’t be afraid, Mary, for you have found favor with God."},{"v":31,"t":"Behold, you will conceive in your womb and give birth to a son, and shall name him ‘Jesus.’"},{"v":32,"t":"He will be great and will be called the Son of the Most High. The Lord God will give him the throne of his father David,"},{"v":33,"t":"and he will reign over the house of Jacob forever. There will be no end to his Kingdom.”"},{"v":34,"t":"Mary said to the angel, “How can this be, seeing I am a virgin?”"},{"v":35,"t":"The angel answered her, “The Holy Spirit will come on you, and the power of the Most High will overshadow you. Therefore also the holy one who is born from you will be called the Son of God."},{"v":36,"t":"Behold, Elizabeth your relative also has conceived a son in her old age; and this is the sixth month with her who was called barren."},{"v":37,"t":"For nothing spoken by God is impossible.”"},{"v":38,"t":"Mary said, “Behold, the servant of the Lord; let it be done to me according to your word.” Then the angel departed from her."},{"v":39,"t":"Mary arose in those days and went into the hill country with haste, into a city of Judah,"},{"v":40,"t":"and entered into the house of Zacharias and greeted Elizabeth."},{"v":41,"t":"When Elizabeth heard Mary’s greeting, the baby leaped in her womb; and Elizabeth was filled with the Holy Spirit."},{"v":42,"t":"She called out with a loud voice and said, “Blessed are you among women, and blessed is the fruit of your womb!"},{"v":43,"t":"Why am I so favored, that the mother of my Lord should come to me?"},{"v":44,"t":"For behold, when the voice of your greeting came into my ears, the baby leaped in my womb for joy!"},{"v":45,"t":"Blessed is she who believed, for there will be a fulfillment of the things which have been spoken to her from the Lord!”"},{"v":46,"t":"Mary said, “My soul magnifies the Lord."},{"v":47,"t":"My spirit has rejoiced in God my Savior,"},{"v":48,"t":"for he has looked at the humble state of his servant. For behold, from now on, all generations will call me blessed."},{"v":49,"t":"For he who is mighty has done great things for me. Holy is his name."},{"v":50,"t":"His mercy is for generations and generations on those who fear him."},{"v":51,"t":"He has shown strength with his arm. He has scattered the proud in the imagination of their hearts."},{"v":52,"t":"He has put down princes from their thrones, and has exalted the lowly."},{"v":53,"t":"He has filled the hungry with good things. He has sent the rich away empty."},{"v":54,"t":"He has given help to Israel, his servant, that he might remember mercy,"},{"v":55,"t":"as he spoke to our fathers, to Abraham and his offspring forever.”"},{"v":56,"t":"Mary stayed with her about three months, and then returned to her house."},{"v":57,"t":"Now the time that Elizabeth should give birth was fulfilled, and she gave birth to a son."},{"v":58,"t":"Her neighbors and her relatives heard that the Lord had magnified his mercy toward her, and they rejoiced with her."},{"v":59,"t":"On the eighth day, they came to circumcise the child; and they would have called him Zacharias, after the name of his father."},{"v":60,"t":"His mother answered, “Not so; but he will be called John.”"},{"v":61,"t":"They said to her, “There is no one among your relatives who is called by this name.”"},{"v":62,"t":"They made signs to his father, what he would have him called."},{"v":63,"t":"He asked for a writing tablet, and wrote, “His name is John.” They all marveled."},{"v":64,"t":"His mouth was opened immediately and his tongue freed, and he spoke, blessing God."},{"v":65,"t":"Fear came on all who lived around them, and all these sayings were talked about throughout all the hill country of Judea."},{"v":66,"t":"All who heard them laid them up in their heart, saying, “What then will this child be?” The hand of the Lord was with him."},{"v":67,"t":"His father Zacharias was filled with the Holy Spirit, and prophesied, saying,"},{"v":68,"t":"“Blessed be the Lord, the God of Israel, for he has visited and redeemed his people;"},{"v":69,"t":"and has raised up a horn of salvation for us in the house of his servant David"},{"v":70,"t":"(as he spoke by the mouth of his holy prophets who have been from of old),"},{"v":71,"t":"salvation from our enemies and from the hand of all who hate us;"},{"v":72,"t":"to show mercy toward our fathers, to remember his holy covenant,"},{"v":73,"t":"the oath which he swore to Abraham our father,"},{"v":74,"t":"to grant to us that we, being delivered out of the hand of our enemies, should serve him without fear,"},{"v":75,"t":"in holiness and righteousness before him all the days of our life."},{"v":76,"t":"And you, child, will be called a prophet of the Most High; for you will go before the face of the Lord to prepare his ways,"},{"v":77,"t":"to give knowledge of salvation to his people by the remission of their sins,"},{"v":78,"t":"because of the tender mercy of our God, by which the dawn from on high will visit us,"},{"v":79,"t":"to shine on those who sit in darkness and the shadow of death; to guide our feet into the way of peace.”"},{"v":80,"t":"The child was growing and becoming strong in spirit, and was in the desert until the day of his public appearance to Israel."}],"hr":[{"v":1,"t":"Kad već mnogi poduzeše sastaviti izvješće o događajima koji se ispuniše među nama -"},{"v":2,"t":"kako nam to predadoše oni koji od početka bijahu očevici i sluge Riječi -"},{"v":3,"t":"pošto sam sve, od početka, pomno ispitao, naumih i ja tebi, vrli Teofile, sve po redu napisati"},{"v":4,"t":"da se tako osvjedočiš o pouzdanosti svega u čemu si poučen."},{"v":5,"t":"U dane Heroda, kralja judejskoga, bijaše neki svećenik imenom Zaharija iz razreda Abijina. Žena mu bijaše od kćeri Aronovih, a ime joj Elizabeta."},{"v":6,"t":"Oboje bijahu pravedni pred Bogom: živjeli su besprijekorno po svim zapovijedima i odredbama Gospodnjim."},{"v":7,"t":"No nisu imali djeteta jer Elizabeta bijaše nerotkinja, a oboje već poodmakle dobi."},{"v":8,"t":"Dok je Zaharija jednom po redu svoga razreda obavljao svećeničku službu pred Bogom,"},{"v":9,"t":"ždrijebom ga zapade po bogoslužnom običaju da uđe u Svetište Gospodnje i prinese kad."},{"v":10,"t":"Za vrijeme kađenice sve je ono mnoštvo naroda vani molilo."},{"v":11,"t":"A njemu se ukaza anđeo Gospodnji. Stajao je s desne strane kadionoga žrtvenika."},{"v":12,"t":"Ugledavši ga, Zaharija se prepade i strah ga spopade."},{"v":13,"t":"No anđeo mu reče: “Ne boj se, Zaharija! Uslišana ti je molitva: žena će ti Elizabeta roditi sina. Nadjenut ćeš mu ime Ivan."},{"v":14,"t":"Bit će ti radost i veselje i rođenje će njegovo mnoge obradovati."},{"v":15,"t":"Bit će doista velik pred Gospodinom. Ni vina ni drugoga opojnog pića neće piti. Duha Svetoga bit će pun već od majčine utrobe."},{"v":16,"t":"Mnoge će sinove Izraelove obratiti Gospodinu, Bogu njihovu."},{"v":17,"t":"Ići će pred njim u duhu i sili Ilijinoj da obrati srce otaca k sinovima i nepokorne k razumnosti pravednih te spremi Gospodinu narod pripravan.”"},{"v":18,"t":"Nato Zaharija reče anđelu: “Po čemu ću ja to razaznati. Ta star sam i žena mi poodmakle dobi.”"},{"v":19,"t":"Anđeo mu odgovori: “Ja sam Gabriel koji stojim pred Bogom. Poslan sam da govorim s tobom i da ti donesem ovu radosnu poruku."},{"v":20,"t":"I evo, budući da nisi povjerovao mojim riječima, koje će se ispuniti u svoje vrijeme, zanijemjet ćeš i nećeš moći govoriti do dana dok se to ne zbude.”"},{"v":21,"t":"Narod je iščekivao Zahariju i čudio se što se toliko zadržao u Svetištu."},{"v":22,"t":"Kad je napokon izašao, nije im mogao ništa reći pa zaključiše da je u Svetištu imao viđenje. Nastojao im se doduše izraziti znakovima, ali osta nijem."},{"v":23,"t":"Kad se navršiše dani njegove službe, otiđe kući."},{"v":24,"t":"Nakon tih dana zatrudnje Elizabeta, njegova žena. Krila se pet mjeseci govoreći:"},{"v":25,"t":"“Evo, to mi je učinio Gospodin u dane kad mu se svidje skinuti s mene sramotu među ljudima.”"},{"v":26,"t":"U šestome mjesecu posla Bog anđela Gabriela u galilejski grad imenom Nazaret"},{"v":27,"t":"k djevici zaručenoj s mužem koji se zvao Josip iz doma Davidova; a djevica se zvala Marija."},{"v":28,"t":"Anđeo uđe k njoj i reče: “Zdravo, milosti puna! Gospodin s tobom!”"},{"v":29,"t":"Na tu se riječ ona smete i stade razmišljati kakav bi to bio pozdrav."},{"v":30,"t":"No anđeo joj reče: “Ne boj se, Marijo! Ta našla si milost u Boga."},{"v":31,"t":"Evo, začet ćeš i roditi sina i nadjenut ćeš mu ime Isus."},{"v":32,"t":"On će biti velik i zvat će se Sin Svevišnjega. Njemu će Gospodin Bog dati prijestolje Davida, oca njegova,"},{"v":33,"t":"i kraljevat će nad domom Jakovljevim uvijeke i njegovu kraljevstvu neće biti kraja.”"},{"v":34,"t":"Nato će Marija anđelu: “Kako će to biti kad ja muža ne poznajem?”"},{"v":35,"t":"Anđeo joj odgovori: “Duh Sveti sići će na te i sila će te Svevišnjega osjeniti. Zato će to čedo i biti sveto, Sin Božji."},{"v":36,"t":"A evo tvoje rođakinje Elizabete: i ona u starosti svojoj zače sina. I njoj, nerotkinjom prozvanoj, ovo je već šesti mjesec."},{"v":37,"t":"Ta Bogu ništa nije nemoguće!”"},{"v":38,"t":"Nato Marija reče: “Evo službenice Gospodnje, neka mi bude po tvojoj riječi!” I anđeo otiđe od nje."},{"v":39,"t":"Tih dana usta Marija i pohiti u Gorje, u grad Judin."},{"v":40,"t":"Uđe u Zaharijinu kuću i pozdravi Elizabetu."},{"v":41,"t":"Čim Elizabeta začu Marijin pozdrav, zaigra joj čedo u utrobi. I napuni se Elizabeta Duha Svetoga"},{"v":42,"t":"i povika iz svega glasa: “Blagoslovljena ti među ženama i blagoslovljen plod utrobe tvoje!"},{"v":43,"t":"Ta otkuda meni da mi dođe majka Gospodina mojega?"},{"v":44,"t":"Gledaj samo! Tek što mi do ušiju doprije glas pozdrava tvojega, zaigra mi od radosti čedo u utrobi."},{"v":45,"t":"Blažena ti što povjerova da će se ispuniti što ti je rečeno od Gospodina!”"},{"v":46,"t":"Tada Marija reče: “Veliča duša moja Gospodina,"},{"v":47,"t":"klikće duh moj u Bogu, mome Spasitelju,"},{"v":48,"t":"što pogleda na neznatnost službenice svoje: odsad će me, evo, svi naraštaji zvati blaženom."},{"v":49,"t":"Jer velika mi djela učini Svesilni, sveto je ime njegovo!"},{"v":50,"t":"Od koljena do koljena dobrota je njegova nad onima što se njega boje."},{"v":51,"t":"Iskaza snagu mišice svoje, rasprši oholice umišljene."},{"v":52,"t":"Silne zbaci s prijestolja, a uzvisi neznatne."},{"v":53,"t":"Gladne napuni dobrima, a bogate otpusti prazne."},{"v":54,"t":"Prihvati Izraela, slugu svoga, kako obeća ocima našim:"},{"v":55,"t":"spomenuti se dobrote svoje prema Abrahamu i potomstvu njegovu dovijeka.”"},{"v":56,"t":"Marija osta s Elizabetom oko tri mjeseca, a onda se vrati kući."},{"v":57,"t":"Elizabeti se međutim navršilo vrijeme da rodi. I porodi sina."},{"v":58,"t":"Kad su njezini susjedi i rođaci čuli da joj Gospodin obilno iskaza dobrotu, radovahu se s njome."},{"v":59,"t":"Osmoga se dana okupe da obrežu dječaka. Htjedoše ga prozvati imenom njegova oca - Zaharija,"},{"v":60,"t":"no mati se njegova usprotivi: “Nipošto, nego zvat će se Ivan!”"},{"v":61,"t":"Rekoše joj na to: “Ta nikoga nema od tvoje rodbine koji bi se tako zvao.”"},{"v":62,"t":"Tada znakovima upitaju oca kojim ga imenom želi prozvati."},{"v":63,"t":"On zaiska pločicu i napisa “Ivan mu je ime!” Svi se začude,"},{"v":64,"t":"a njemu se umah otvoriše usta i jezik te progovori blagoslivljajući Boga."},{"v":65,"t":"Strah obuze sve njihove susjede, a po svem su se Gorju judejskom razglašavali svi ti događaji."},{"v":66,"t":"I koji su god čuli, razmišljahu o tome pitajući se: “Što li će biti od ovoga djeteta?” Uistinu, ruka Gospodnja bijaše s njime."},{"v":67,"t":"A Zaharija, otac njegov, napuni se Duha Svetoga i stade prorokovati:"},{"v":68,"t":"“Blagoslovljen Gospodin Bog Izraelov, što pohodi i otkupi narod svoj!"},{"v":69,"t":"Podiže nam snagu spasenja u domu Davida, sluge svojega,"},{"v":70,"t":"kao što obeća na usta svetih proroka svojih odvijeka:"},{"v":71,"t":"spasiti nas od neprijatelja naših i od ruke sviju koji nas mrze;"},{"v":72,"t":"iskazati dobrotu ocima našim i sjetiti se svetog Saveza svojega,"},{"v":73,"t":"zakletve kojom se zakle Abrahamu, ocu našemu: da će nam dati"},{"v":74,"t":"te mu, izbavljeni iz ruku neprijatelja, služimo bez straha"},{"v":75,"t":"u svetosti i pravednosti pred njim u sve dane svoje."},{"v":76,"t":"A ti, dijete, prorok ćeš se Svevišnjega zvati jer ćeš ići pred Gospodinom da mu pripraviš putove,"},{"v":77,"t":"da pružiš spoznaju spasenja narodu njegovu po otpuštenju grijeha njihovih,"},{"v":78,"t":"darom premilosrdnog srca Boga našega po kojem će nas pohoditi Mlado sunce s visine"},{"v":79,"t":"da obasja one što sjede u tmini i sjeni smrtnoj, da upravi noge naše na put mira.”"},{"v":80,"t":"Dječak je međutim rastao i duhom jačao. Boravio je u pustinji sve do dana svoga javnog nastupa pred Izraelom."}]},"2":{"fa":[{"v":1,"t":"و در آن ایام حکمی از اوغسطس قیصرصادر گشت که تمام ربع مسکون را اسم نویسی کنند."},{"v":2,"t":"و این اسم نویسی اول شد، هنگامی که کیرینیوس والی سوریه بود."},{"v":3,"t":"پس همه مردم هر یک به شهر خود برای اسم نویسی می‌رفتند."},{"v":4,"t":"و یوسف نیز از جلیل از بلده ناصره به یهودیه به شهر داود که بیت لحم نام داشت، رفت. زیرا که او از خاندان و آل داود بود."},{"v":5,"t":"تا نام او بامریم که نامزد او بود و نزدیک به زاییدن بود، ثبت گردد."},{"v":6,"t":"و وقتی که ایشان در آنجا بودند، هنگام وضع حمل او رسیده،"},{"v":7,"t":"پسر نخستین خود رازایید. و او را در قنداقه پیچیده، در آخورخوابانید. زیرا که برای ایشان در منزل جای نبود."},{"v":8,"t":"و در آن نواحی، شبانان در صحرا بسرمی بردند و در شب پاسبانی گله های خویش می‌کردند."},{"v":9,"t":"ناگاه فرشته خداوند بر ایشان ظاهرشد و کبریایی خداوند بر گرد ایشان تابید و بغایت ترسان گشتند."},{"v":10,"t":"فرشته ایشان را گفت: «مترسید، زیرا اینک بشارت خوشی عظیم به شما می‌دهم که برای جمیع قوم خواهد بود."},{"v":11,"t":"که امروز برای شما در شهر داود، نجات‌دهنده‌ای که مسیح خداوند باشد متولد شد."},{"v":12,"t":"و علامت برای شمااین است که طفلی در قنداقه پیچیده و در آخورخوابیده خواهید یافت.»"},{"v":13,"t":"در همان حال فوجی از لشکر آسمانی با فرشته حاضر شده، خدا راتسبیح‌کنان می‌گفتند:"},{"v":14,"t":"«خدا را در اعلی علیین جلال و بر زمین سلامتی و در میان مردم رضامندی باد.»"},{"v":15,"t":"و چون فرشتگان از نزد ایشان به آسمان رفتند، شبانان با یکدیگر گفتند: «الان به بیت لحم برویم و این چیزی را که واقع شده و خداوند آن را به ما اعلام نموده است ببینیم.»"},{"v":16,"t":"پس به شتاب رفته، مریم و یوسف و آن طفل رادر آخور خوابیده یافتند."},{"v":17,"t":"چون این را دیدند، آن سخنی را که درباره طفل بدیشان گفته شده بود، شهرت دادند."},{"v":18,"t":"و هر‌که می‌شنید از آنچه شبانان بدیشان گفتند، تعجب می‌نمود."},{"v":19,"t":"امامریم در دل خود متفکر شده، این همه سخنان رانگاه می‌داشت."},{"v":20,"t":"و شبانان خدا را تمجید وحمدکنان برگشتند، به‌سبب همه آن اموری که دیده و شنیده بودند چنانکه به ایشان گفته شده بود."},{"v":21,"t":"و چون روز هشتم، وقت ختنه طفل رسید، او را عیسی نام نهادند، چنانکه فرشته قبل از قرارگرفتن او در رحم، او را نامیده بود."},{"v":22,"t":"و چون ایام تطهیر ایشان برحسب شریعت موسی رسید، او رابه اورشلیم بردند تا به خداوند بگذرانند."},{"v":23,"t":"چنانکه در شریعت خداوند مکتوب است که هر ذکوری که رحم را گشاید، مقدس خداوندخوانده شود."},{"v":24,"t":"و تا قربانی گذرانند، چنانکه درشریعت خداوند مقرر است، یعنی جفت فاخته‌ای یا دو جوجه کبوتر."},{"v":25,"t":"و اینک شخصی شمعون نام در اورشلیم بود که مرد صالح و متقی و منتظر تسلی اسرائیل بود و روح‌القدس بر وی بود."},{"v":26,"t":"و از روح‌القدس بدو وحی رسیده بود که، تا مسیح خداوند را نبینی موت را نخواهی دید."},{"v":27,"t":"پس به راهنمایی روح، به هیکل درآمد وچون والدینش آن طفل یعنی عیسی را آوردند تا رسوم شریعت را بجهت او بعمل آورند،"},{"v":28,"t":"او رادر آغوش خود کشیده و خدا را متبارک خوانده، گفت:"},{"v":29,"t":"«الحال‌ای خداوند بنده خود را رخصت می‌دهی، به سلامتی برحسب کلام خود."},{"v":30,"t":"زیراکه چشمان من نجات تو را دیده است،"},{"v":31,"t":"که آن راپیش روی جمیع امت‌ها مهیا ساختی."},{"v":32,"t":"نوری که کشف حجاب برای امت‌ها کند و قوم تواسرائیل را جلال بود.»"},{"v":33,"t":"و یوسف و مادرش ازآنچه درباره او گفته شد، تعجب نمودند."},{"v":34,"t":"پس شمعون ایشان را برکت داده، به مادرش مریم گفت: «اینک این طفل قرار داده شد، برای افتادن وبرخاستن بسیاری از آل اسرائیل و برای آیتی که به خلاف آن خواهند گفت."},{"v":35,"t":"و در قلب تو نیزشمشیری فرو خواهد رفت، تا افکار قلوب بسیاری مکشوف شود.»"},{"v":36,"t":"و زنی نبیه بود، حنا نام، دختر فنوئیل ازسبط اشیر بسیار سالخورده، که از زمان بکارت هفت سال با شوهر بسر برده بود."},{"v":37,"t":"و قریب به هشتاد و چهار سال بود که او بیوه گشته ازهیکل جدا نمی شد، بلکه شبانه‌روز به روزه ومناجات در عبادت مشغول می‌بود."},{"v":38,"t":"او درهمان ساعت در‌آمده، خدا را شکر نمود ودرباره او به همه منتظرین نجات در اورشلیم، تکلم نمود."},{"v":39,"t":"و چون تمامی رسوم شریعت خداوند را به پایان برده بودند، به شهر خود ناصره جلیل مراجعت کردند."},{"v":40,"t":"و طفل نمو کرده، به روح قوی می‌گشت و از حکمت پر شده، فیض خدا بروی می‌بود."},{"v":41,"t":"و والدین او هر ساله بجهت عید فصح، به اورشلیم می‌رفتند."},{"v":42,"t":"و چون دوازده ساله شد، موافق رسم عید، به اورشلیم آمدند."},{"v":43,"t":"وچون روزها را تمام کرده مراجعت می‌نمودند، آن طفل یعنی عیسی، در اورشلیم توقف نمودو یوسف و مادرش نمی دانستند."},{"v":44,"t":"بلکه چون گمان می‌بردند که او در قافله است، سفریکروزه کردند و او را در میان خویشان وآشنایان خود می‌جستند."},{"v":45,"t":"و چون او را نیافتند، در طلب او به اورشلیم برگشتند."},{"v":46,"t":"و بعد ازسه روز، او را در هیکل یافتند که در میان معلمان نشسته، سخنان ایشان را می‌شنود و ازایشان سوال همی کرد."},{"v":47,"t":"و هر‌که سخن او رامی شنید، از فهم و جوابهای او متحیرمی گشت."},{"v":48,"t":"چون ایشان او را دیدند، مضطرب شدند. پس مادرش به وی گفت: «ای فرزند چرا با ماچنین کردی؟ اینک پدرت و من غمناک گشته تو را جستجو می‌کردیم.»"},{"v":49,"t":"او به ایشان گفت: «از بهر‌چه مرا طلب می‌کردید، مگرندانسته‌اید که باید من در امور پدر خود باشم؟»"},{"v":50,"t":"ولی آن سخنی را که بدیشان گفت، نفهمیدند."},{"v":51,"t":"پس با ایشان روانه شده، به ناصره آمد و مطیع ایشان می‌بود و مادر او تمامی این امور را درخاطر خود نگاه می‌داشت."},{"v":52,"t":"و عیسی درحکمت و قامت و رضامندی نزد خدا و مردم ترقی می‌کرد."}],"en":[{"v":1,"t":"Now in those days, a decree went out from Caesar Augustus that all the world should be enrolled."},{"v":2,"t":"This was the first enrollment made when Quirinius was governor of Syria."},{"v":3,"t":"All went to enroll themselves, everyone to his own city."},{"v":4,"t":"Joseph also went up from Galilee, out of the city of Nazareth, into Judea, to David’s city, which is called Bethlehem, because he was of the house and family of David,"},{"v":5,"t":"to enroll himself with Mary, who was pledged to be married to him as wife, being pregnant."},{"v":6,"t":"While they were there, the day had come for her to give birth."},{"v":7,"t":"She gave birth to her firstborn son. She wrapped him in bands of cloth and laid him in a feeding trough, because there was no room for them in the inn."},{"v":8,"t":"There were shepherds in the same country staying in the field, and keeping watch by night over their flock."},{"v":9,"t":"Behold, an angel of the Lord stood by them, and the glory of the Lord shone around them, and they were terrified."},{"v":10,"t":"The angel said to them, “Don’t be afraid, for behold, I bring you good news of great joy which will be to all the people."},{"v":11,"t":"For there is born to you today, in David’s city, a Savior, who is Christ the Lord."},{"v":12,"t":"This is the sign to you: you will find a baby wrapped in strips of cloth, lying in a feeding trough.”"},{"v":13,"t":"Suddenly, there was with the angel a multitude of the heavenly army praising God and saying,"},{"v":14,"t":"“Glory to God in the highest, on earth peace, good will toward men.”"},{"v":15,"t":"When the angels went away from them into the sky, the shepherds said to one another, “Let’s go to Bethlehem, now, and see this thing that has happened, which the Lord has made known to us.”"},{"v":16,"t":"They came with haste and found both Mary and Joseph, and the baby was lying in the feeding trough."},{"v":17,"t":"When they saw it, they publicized widely the saying which was spoken to them about this child."},{"v":18,"t":"All who heard it wondered at the things which were spoken to them by the shepherds."},{"v":19,"t":"But Mary kept all these sayings, pondering them in her heart."},{"v":20,"t":"The shepherds returned, glorifying and praising God for all the things that they had heard and seen, just as it was told them."},{"v":21,"t":"When eight days were fulfilled for the circumcision of the child, his name was called Jesus, which was given by the angel before he was conceived in the womb."},{"v":22,"t":"When the days of their purification according to the law of Moses were fulfilled, they brought him up to Jerusalem to present him to the Lord"},{"v":23,"t":"(as it is written in the law of the Lord, “Every male who opens the womb shall be called holy to the Lord”),"},{"v":24,"t":"and to offer a sacrifice according to that which is said in the law of the Lord, “A pair of turtledoves, or two young pigeons.”"},{"v":25,"t":"Behold, there was a man in Jerusalem whose name was Simeon. This man was righteous and devout, looking for the consolation of Israel, and the Holy Spirit was on him."},{"v":26,"t":"It had been revealed to him by the Holy Spirit that he should not see death before he had seen the Lord’s Christ."},{"v":27,"t":"He came in the Spirit into the temple. When the parents brought in the child, Jesus, that they might do concerning him according to the custom of the law,"},{"v":28,"t":"then he received him into his arms and blessed God, and said,"},{"v":29,"t":"“Now you are releasing your servant, Master, according to your word, in peace;"},{"v":30,"t":"for my eyes have seen your salvation,"},{"v":31,"t":"which you have prepared before the face of all peoples;"},{"v":32,"t":"a light for revelation to the nations, and the glory of your people Israel.”"},{"v":33,"t":"Joseph and his mother were marveling at the things which were spoken concerning him."},{"v":34,"t":"Simeon blessed them, and said to Mary, his mother, “Behold, this child is appointed for the falling and the rising of many in Israel, and for a sign which is spoken against."},{"v":35,"t":"Yes, a sword will pierce through your own soul, that the thoughts of many hearts may be revealed.”"},{"v":36,"t":"There was one Anna, a prophetess, the daughter of Phanuel, of the tribe of Asher (she was of a great age, having lived with a husband seven years from her virginity,"},{"v":37,"t":"and she had been a widow for about eighty-four years), who didn’t depart from the temple, worshiping with fastings and petitions night and day."},{"v":38,"t":"Coming up at that very hour, she gave thanks to the Lord, and spoke of him to all those who were looking for redemption in Jerusalem."},{"v":39,"t":"When they had accomplished all things that were according to the law of the Lord, they returned into Galilee, to their own city, Nazareth."},{"v":40,"t":"The child was growing, and was becoming strong in spirit, being filled with wisdom, and the grace of God was upon him."},{"v":41,"t":"His parents went every year to Jerusalem at the feast of the Passover."},{"v":42,"t":"When he was twelve years old, they went up to Jerusalem according to the custom of the feast;"},{"v":43,"t":"and when they had fulfilled the days, as they were returning, the boy Jesus stayed behind in Jerusalem. Joseph and his mother didn’t know it,"},{"v":44,"t":"but supposing him to be in the company, they went a day’s journey; and they looked for him among their relatives and acquaintances."},{"v":45,"t":"When they didn’t find him, they returned to Jerusalem, looking for him."},{"v":46,"t":"After three days they found him in the temple, sitting in the middle of the teachers, both listening to them and asking them questions."},{"v":47,"t":"All who heard him were amazed at his understanding and his answers."},{"v":48,"t":"When they saw him, they were astonished; and his mother said to him, “Son, why have you treated us this way? Behold, your father and I were anxiously looking for you.”"},{"v":49,"t":"He said to them, “Why were you looking for me? Didn’t you know that I must be in my Father’s house?”"},{"v":50,"t":"They didn’t understand the saying which he spoke to them."},{"v":51,"t":"And he went down with them and came to Nazareth. He was subject to them, and his mother kept all these sayings in her heart."},{"v":52,"t":"And Jesus increased in wisdom and stature, and in favor with God and men."}],"hr":[{"v":1,"t":"U one dane izađe naredba cara Augusta da se provede popis svega svijeta."},{"v":2,"t":"Bijaše to prvi popis izvršen za Kvirinijeva upravljanja Sirijom."},{"v":3,"t":"Svi su išli na popis, svaki u svoj grad."},{"v":4,"t":"Tako i Josip, budući da je bio iz doma i loze Davidove, uziđe iz Galileje, iz grada Nazareta, u Judeju - u grad Davidov, koji se zove Betlehem -"},{"v":5,"t":"da se podvrgne popisu zajedno sa svojom zaručnicom Marijom koja bijaše trudna."},{"v":6,"t":"I dok se bili ondje, navršilo joj se vrijeme da rodi."},{"v":7,"t":"I porodi sina svoga, prvorođenca, povi ga i položi u jasle jer za njih nije bilo mjesta u svratištu."},{"v":8,"t":"A u tom kraju bijahu pastiri: pod vedrim su nebom čuvali noćnu stražu kod svojih stada."},{"v":9,"t":"Anđeo im Gospodnji pristupi i slava ih Gospodnja obasja! Silno se prestrašiše."},{"v":10,"t":"No anđeo im reče: “Ne bojte se! Evo javljam vam blagovijest, veliku radost za sav narod!"},{"v":11,"t":"Danas vam se u gradu Davidovu rodio Spasitelj - Krist, Gospodin."},{"v":12,"t":"I evo vam znaka: naći ćete novorođenče povijeno gdje leži u jaslama.”"},{"v":13,"t":"I odjednom se anđelu pridruži silna nebeska vojska hvaleći Boga i govoreći:"},{"v":14,"t":"“Slava na visinama Bogu, a na zemlji mir ljudima, miljenicima njegovim!”"},{"v":15,"t":"Čim anđeli otiđoše od njih na nebo, pastiri stanu poticati jedni druge: “Hajdemo dakle do Betlehema. Pogledajmo što se to dogodilo, događaj koji nam obznani Gospodin.”"},{"v":16,"t":"I pohite te pronađu Mariju, Josipa i novorođenče gdje leži u jaslama."},{"v":17,"t":"Pošto sve pogledaše, ispripovijediše što im bijaše rečeno o tom djetetu."},{"v":18,"t":"A svi koji su to čuli divili se tome što su im pripovijedali pastiri."},{"v":19,"t":"Marija u sebi pohranjivaše sve te događaje i prebiraše ih u svome srcu."},{"v":20,"t":"Pastiri se zatim vratiše slaveći i hvaleći Boga za sve što su čuli i vidjeli kako im je bilo rečeno."},{"v":21,"t":"Kad se navršilo osam dana da bude obrezan, nadjenuše mu ime Isus, kako ga je bio prozvao anđeo prije njegova začeća."},{"v":22,"t":"Kad se zatim po Mojsijevu Zakonu navršiše dani njihova čišćenja, poniješe ga u Jeruzalem da ga prikažu Gospodinu -"},{"v":23,"t":"kao što piše u Zakonu Gospodnjem: Svako muško prvorođenče neka se posveti Gospodinu! -"},{"v":24,"t":"i da prinesu žrtvu kako je rečeno u Zakonu Gospodnjem: dvije grlice ili dva golubića."},{"v":25,"t":"Živio tada u Jeruzalemu čovjek po imenu Šimun. Taj čovjek, pravedan i bogobojazan, iščekivaše Utjehu Izraelovu i Duh Sveti bijaše na njemu."},{"v":26,"t":"Objavio mu Duh Sveti da neće vidjeti smrti dok ne vidi Pomazanika Gospodnjega."},{"v":27,"t":"Ponukan od Duha, dođe u Hram. I kad roditelji uniješe dijete Isusa da obave što o njemu propisuje Zakon,"},{"v":28,"t":"primi ga on u naručje, blagoslovi Boga i reče:"},{"v":29,"t":"“Sad otpuštaš slugu svojega, Gospodaru, po riječi svojoj, u miru!"},{"v":30,"t":"Ta vidješe oči moje spasenje tvoje,"},{"v":31,"t":"koje si pripravio pred licem svih naroda:"},{"v":32,"t":"svjetlost na prosvjetljenje naroda, slavu puka svoga izraelskoga.”"},{"v":33,"t":"Otac njegov i majka divili se što se to o njemu govori."},{"v":34,"t":"Šimun ih blagoslovi i reče Mariji, majci njegovoj: “Ovaj je evo postavljen na propast i uzdignuće mnogima u Izraelu i za znak osporavan -"},{"v":35,"t":"a i tebi će samoj mač probosti dušu - da se razotkriju namisli mnogih srdaca!”"},{"v":36,"t":"A bijaše neka proročica Ana, kći Penuelova, iz plemena Ašerova, žena veoma odmakla u godinama. Nakon djevojaštva živjela je s mužem sedam godina,"},{"v":37,"t":"a sama kao udovica do osamdeset i četvrte. Nije napuštala Hrama, nego je postovima i molitvama danju i noću služila Bogu."},{"v":38,"t":"Upravo u taj čas nadođe. Hvalila je Boga i svima koji iščekivahu otkupljenje Jeruzalema pripovijedala o djetetu."},{"v":39,"t":"Kad obaviše sve po Zakonu Gospodnjem, vratiše se u Galileju, u svoj grad Nazaret."},{"v":40,"t":"A dijete je raslo, jačalo i napunjalo se mudrosti i milost je Božja bila na njemu."},{"v":41,"t":"Njegovi su roditelji svake godine o blagdanu Pashe išli u Jeruzalem."},{"v":42,"t":"Kad mu bijaše dvanaest godina, uziđoše po običaju blagdanskom."},{"v":43,"t":"Kad su minuli ti dani, vraćahu se oni, a dječak Isus osta u Jeruzalemu, a da nisu znali njegovi roditelji."},{"v":44,"t":"Uvjereni da je među suputnicima, odoše dan hoda, a onda ga stanu tražiti među rodbinom i znancima."},{"v":45,"t":"I kad ga ne nađu, vrate se u Jeruzalem tražeći ga."},{"v":46,"t":"Nakon tri dana nađoše ga u Hramu gdje sjedi posred učitelja, sluša ih i pita."},{"v":47,"t":"Svi koji ga slušahu bijahu zaneseni razumnošću i odgovorima njegovim."},{"v":48,"t":"Kad ga ugledaše, zapanjiše se, a majka mu njegova reče: “Sinko, zašto si nam to učinio? Gle, otac tvoj i ja žalosni smo te tražili.”"},{"v":49,"t":"A on im reče: “Zašto ste me tražili? Niste li znali da mi je biti u onome što je Oca mojega?”"},{"v":50,"t":"Oni ne razumješe riječi koju im reče."},{"v":51,"t":"I siđe s njima, dođe u Nazaret i bijaše im poslušan. A majka je njegova brižno čuvala sve ove uspomene u svom srcu."},{"v":52,"t":"A Isus napredovaše u mudrosti, dobi i milosti kod Boga i ljudi."}]},"3":{"fa":[{"v":1,"t":"و در سال پانزدهم از سلطنت طیباریوس قیصر، در وقتی که پنطیوس پیلاطس، والی یهودیه بود و هیرودیس، تیترارک جلیل وبرادرش فیلپس تیترارک ایطوریه تراخونیتس ولیسانیوس تیترارک آبلیه"},{"v":2,"t":"و حنا و قیافا روسای کهنه بودند، کلام خدا به یحیی ابن زکریا در بیابان نازل شده،"},{"v":3,"t":"به تمامی حوالی اردن آمده، به تعمیدتوبه بجهت آمرزش گناهان موعظه می‌کرد."},{"v":4,"t":"چنانچه مکتوب است در صحیفه کلمات اشعیای نبی که می‌گوید: «صدای ندا کننده‌ای دربیابان که راه خداوند را مهیا سازید و طرق او راراست نمایید."},{"v":5,"t":"هر وادی انباشته و هر کوه و تلی پست و هر کجی راست و هر راه ناهموار صاف خواهد شد"},{"v":6,"t":"و تمامی بشر نجات خدا را خواهنددید.»"},{"v":7,"t":"آنگاه به آن جماعتی که برای تعمید وی بیرون می‌آمدند، گفت: «ای افعی‌زادگان، که شمارا نشان داد که از غضب آینده بگریزید؟"},{"v":8,"t":"پس ثمرات مناسب توبه بیاورید و در خاطر خود این سخن را راه مدهید که ابراهیم پدر ماست، زیرا به شما می‌گویم خدا قادر است که از این سنگها، فرزندان برای ابراهیم برانگیزاند."},{"v":9,"t":"و الان نیز تیشه بر ریشه درختان نهاده شده است، پس هر درختی که میوه نیکو نیاورد، بریده و در آتش افکنده می‌شود.»"},{"v":10,"t":"پس مردم از وی سوال نموده گفتند: «چه کنیم؟»"},{"v":11,"t":"او در جواب ایشان گفت: «هر‌که دوجامه دارد، به آنکه ندارد بدهد. و هرکه خوراک دارد نیز چنین کند.»"},{"v":12,"t":"و باجگیران نیز برای تعمید آمده، بدو گفتند: «ای استاد چه کنیم؟»"},{"v":13,"t":"بدیشان گفت: «زیادتر از آنچه مقرر است، مگیرید.»"},{"v":14,"t":"سپاهیان نیز از او پرسیده، گفتند: «ماچه کنیم؟» به ایشان گفت: «بر کسی ظلم مکنید وبر هیچ‌کس افترا مزنید و به مواجب خود اکتفاکنید.»"},{"v":15,"t":"و هنگامی که قوم مترصد می‌بودند و همه در خاطر خود درباره یحیی تفکر می‌نمودندکه این مسیح است یا نه،"},{"v":16,"t":"یحیی به همه متوجه شده گفت: «من شما را به آب تعمیدمی دهم، لیکن شخصی تواناتر از من می‌آید که لیاقت آن ندارم که بند نعلین او را باز کنم. اوشما را به روح‌القدس و آتش تعمید خواهد داد."},{"v":17,"t":"او غربال خود را به‌دست خود دارد وخرمن خویش را پاک کرده، گندم را در انبارخود ذخیره خواهد نمود و کاه را در آتشی که خاموشی نمی پذیرد خواهد سوزانید.»"},{"v":18,"t":"وبه نصایح بسیار دیگر، قوم را بشارت می‌داد."},{"v":19,"t":"اما هیرودیس تیترارک چون به‌سبب هیرودیا، زن برادر او فیلپس و سایر بدیهایی که هیرودیس کرده بود از وی توبیخ یافت،"},{"v":20,"t":"این رانیز بر همه افزود که یحیی را در زندان حبس نمود."},{"v":21,"t":"اما چون تمامی قوم تعمید یافته بودند وعیسی هم تعمید گرفته دعا می‌کرد، آسمان شکافته شد"},{"v":22,"t":"و روح‌القدس به هیات جسمانی، مانند کبوتری بر او نازل شد. و آوازی از آسمان در‌رسید که تو پسر حبیب من هستی که به توخشنودم."},{"v":23,"t":"و خود عیسی وقتی که شروع کرد، قریب به سی ساله بود. و حسب گمان خلق، پسر یوسف ابن هالی"},{"v":24,"t":"ابن متات، بن لاوی، بن ملکی، بن ینا، بن یوسف،"},{"v":25,"t":"ابن متاتیا، بن آموس، بن ناحوم، بن حسلی، بن نجی،"},{"v":26,"t":"ابن مات، بن متاتیا، بن شمعی، بن یوسف، بن یهودا،"},{"v":27,"t":"ابن یوحنا، بن ریسا، بن زروبابل، بن سالتیئیل، بن نیری،"},{"v":28,"t":"ابن ملکی، بن ادی، بن قوسام، بن ایلمودام، بن عیر،"},{"v":29,"t":"ابن یوسی، بن ایلعاذر، بن یوریم، بن متات، بن لاوی،"},{"v":30,"t":"ابن شمعون، بن یهودا، بن یوسف، بن یونان، بن ایلیاقیم،"},{"v":31,"t":"ابن ملیا، بن مینان، بن متاتا بن ناتان، بن داود،"},{"v":32,"t":"ابن یسی، بن عوبید، بن بوعز، بن شلمون، بن نحشون،"},{"v":33,"t":"ابن عمیناداب، بن ارام، بن حصرون، بن فارص، بن یهودا،"},{"v":34,"t":"ابن یعقوب، بن اسحق، بن ابراهیم، بن تارح، بن ناحور،"},{"v":35,"t":"ابن سروج، بن رعور، بن فالج، بن عابر، بن صالح،"},{"v":36,"t":"ابن قینان، بن ارفکشاد، بن سام، بن نوح، بن لامک،"},{"v":37,"t":"ابن متوشالح، بن خنوخ، بن یارد، بن مهللئیل، بن قینان،"},{"v":38,"t":"ابن انوش، بن شیث، بن آدم، بن الله."}],"en":[{"v":1,"t":"Now in the fifteenth year of the reign of Tiberius Caesar, Pontius Pilate being governor of Judea, and Herod being tetrarch of Galilee, and his brother Philip tetrarch of the region of Ituraea and Trachonitis, and Lysanias tetrarch of Abilene,"},{"v":2,"t":"during the high priesthood of Annas and Caiaphas, the word of God came to John, the son of Zacharias, in the wilderness."},{"v":3,"t":"He came into all the region around the Jordan, preaching the baptism of repentance for remission of sins."},{"v":4,"t":"As it is written in the book of the words of Isaiah the prophet, “The voice of one crying in the wilderness, ‘Make ready the way of the Lord. Make his paths straight."},{"v":5,"t":"Every valley will be filled. Every mountain and hill will be brought low. The crooked will become straight, and the rough ways smooth."},{"v":6,"t":"All flesh will see God’s salvation.’”"},{"v":7,"t":"He said therefore to the multitudes who went out to be baptized by him, “You offspring of vipers, who warned you to flee from the wrath to come?"},{"v":8,"t":"Therefore produce fruits worthy of repentance, and don’t begin to say among yourselves, ‘We have Abraham for our father;’ for I tell you that God is able to raise up children to Abraham from these stones!"},{"v":9,"t":"Even now the ax also lies at the root of the trees. Every tree therefore that doesn’t produce good fruit is cut down and thrown into the fire.”"},{"v":10,"t":"The multitudes asked him, “What then must we do?”"},{"v":11,"t":"He answered them, “He who has two coats, let him give to him who has none. He who has food, let him do likewise.”"},{"v":12,"t":"Tax collectors also came to be baptized, and they said to him, “Teacher, what must we do?”"},{"v":13,"t":"He said to them, “Collect no more than that which is appointed to you.”"},{"v":14,"t":"Soldiers also asked him, saying, “What about us? What must we do?” He said to them, “Extort from no one by violence, neither accuse anyone wrongfully. Be content with your wages.”"},{"v":15,"t":"As the people were in expectation, and all men reasoned in their hearts concerning John, whether perhaps he was the Christ,"},{"v":16,"t":"John answered them all, “I indeed baptize you with water, but he comes who is mightier than I, the strap of whose sandals I am not worthy to loosen. He will baptize you in the Holy Spirit and fire."},{"v":17,"t":"His winnowing fan is in his hand, and he will thoroughly cleanse his threshing floor, and will gather the wheat into his barn; but he will burn up the chaff with unquenchable fire.”"},{"v":18,"t":"Then with many other exhortations he preached good news to the people,"},{"v":19,"t":"but Herod the tetrarch, being reproved by him for Herodias, his brother’s wife, and for all the evil things which Herod had done,"},{"v":20,"t":"added this also to them all, that he shut up John in prison."},{"v":21,"t":"Now when all the people were baptized, Jesus also had been baptized and was praying. The sky was opened,"},{"v":22,"t":"and the Holy Spirit descended in a bodily form like a dove on him; and a voice came out of the sky, saying “You are my beloved Son. In you I am well pleased.”"},{"v":23,"t":"Jesus himself, when he began to teach, was about thirty years old, being the son (as was supposed) of Joseph, the son of Heli,"},{"v":24,"t":"the son of Matthat, the son of Levi, the son of Melchi, the son of Jannai, the son of Joseph,"},{"v":25,"t":"the son of Mattathias, the son of Amos, the son of Nahum, the son of Esli, the son of Naggai,"},{"v":26,"t":"the son of Maath, the son of Mattathias, the son of Semein, the son of Joseph, the son of Judah,"},{"v":27,"t":"the son of Joanan, the son of Rhesa, the son of Zerubbabel, the son of Shealtiel, the son of Neri,"},{"v":28,"t":"the son of Melchi, the son of Addi, the son of Cosam, the son of Elmodam, the son of Er,"},{"v":29,"t":"the son of Jose, the son of Eliezer, the son of Jorim, the son of Matthat, the son of Levi,"},{"v":30,"t":"the son of Simeon, the son of Judah, the son of Joseph, the son of Jonan, the son of Eliakim,"},{"v":31,"t":"the son of Melea, the son of Menan, the son of Mattatha, the son of Nathan, the son of David,"},{"v":32,"t":"the son of Jesse, the son of Obed, the son of Boaz, the son of Salmon, the son of Nahshon,"},{"v":33,"t":"the son of Amminadab, the son of Aram, the son of Hezron, the son of Perez, the son of Judah,"},{"v":34,"t":"the son of Jacob, the son of Isaac, the son of Abraham, the son of Terah, the son of Nahor,"},{"v":35,"t":"the son of Serug, the son of Reu, the son of Peleg, the son of Eber, the son of Shelah,"},{"v":36,"t":"the son of Cainan, the son of Arphaxad, the son of Shem, the son of Noah, the son of Lamech,"},{"v":37,"t":"the son of Methuselah, the son of Enoch, the son of Jared, the son of Mahalaleel, the son of Cainan,"},{"v":38,"t":"the son of Enos, the son of Seth, the son of Adam, the son of God."}],"hr":[{"v":1,"t":"Petnaeste godine vladanja cara Tiberija, dok je upravitelj Judeje bio Poncije Pilat, tetrarh Galileje Herod, a njegov brat Filip tetrarh Itureje i zemlje trahonitidske, i Lizanije tetrarh Abilene,"},{"v":2,"t":"za velikog svećenika Ane i Kajfe, dođe riječ Božja Ivanu, sinu Zaharijinu, u pustinji."},{"v":3,"t":"On obiđe svu okolicu jordansku propovijedajući obraćeničko krštenje na otpuštenje grijeha"},{"v":4,"t":"kao što je pisano u Knjizi besjeda Izaije proroka: Glas viče u pustinji: Pripravite put Gospodinu, poravnite mu staze!"},{"v":5,"t":"Svaka dolina neka se ispuni, svaka gora i brežuljak neka se slegne! Što je krivudavo, neka se izravna, a hrapavi putovi neka se izglade!"},{"v":6,"t":"I svako će tijelo vidjeti spasenje Božje."},{"v":7,"t":"Govoraše dakle mnoštvu koje je dolazilo da se krsti: “Leglo gujinje! Tko vas samo upozori da bježite od skore srdžbe?"},{"v":8,"t":"Donosite dakle plodove dostojne obraćenja. I nemojte početi u sebi govoriti: 'Imamo oca Abrahama!' Jer, kažem vam: Bog iz ovog kamenja može podići djecu Abrahamovu."},{"v":9,"t":"Već je sjekira položena na korijen stablima: svako dakle stablo koje ne donosi dobra roda siječe se i u oganj baca.”"},{"v":10,"t":"Pitalo ga mnoštvo: “Što nam je dakle činiti?”"},{"v":11,"t":"On im odgovaraše: “Tko ima dvije haljine, neka podijeli s onim koji nema. U koga ima hrane, neka učini isto tako.”"},{"v":12,"t":"Dođoše krstiti se i carinici pa ga pitahu: “Učitelju, što nam je činiti?”"},{"v":13,"t":"Reče im: “Ne utjerujte više nego što vam je određeno.”"},{"v":14,"t":"Pitahu ga i vojnici: “A nama, što je nama činiti?” I reče im: “Nikome ne činite nasilja, nikoga krivo ne prijavljujte i budite zadovoljni svojom plaćom.”"},{"v":15,"t":"Narod bijaše u iščekivanju i svi se u srcu pitahu o Ivanu nije li on možda Krist."},{"v":16,"t":"Zato im Ivan svima reče: “Ja vas, istina, vodom krstim. Ali dolazi jači od mene. Ja nisam dostojan odriješiti mu remenje na obući. On će vas krstiti Duhom Svetim i ognjem."},{"v":17,"t":"U ruci mu vijača da pročisti gumno svoje i sabere žito u žitnicu svoju, a pljevu će spaliti ognjem neugasivim.”"},{"v":18,"t":"I mnogim je drugim pobudama Ivan narodu navješćivao evanđelje."},{"v":19,"t":"A Heroda je tetrarha Ivan prekorio zbog Herodijade, žene njegova brata i zbog svih njegovih zlodjela."},{"v":20,"t":"Svemu tome nadoda Herod još i ovo: zatvori Ivana u tamnicu."},{"v":21,"t":"Kad se krstio sav narod, krstio se i Isus. I dok se molio, rastvori se nebo,"},{"v":22,"t":"siđe na nj Duh Sveti u tjelesnom obličju, poput goluba, a glas se s neba zaori: “Ti si Sin moj, Ljubljeni! U tebi mi sva milina!”"},{"v":23,"t":"Kad je Isus nastupio, bilo mu je oko trideset godina. Bijaše - kako se smatralo - sin Josipov, Elijev,"},{"v":24,"t":"Matatov, Levijev, Malkijev, Janajev, Josipov."},{"v":25,"t":"Matatijin, Amosov, Naumov, Heslijev, Nagajev,"},{"v":26,"t":"Mahatov, Matatijin, Šimijev, Josehov, Jodin,"},{"v":27,"t":"Johananov, Resin, Zerubabelov, Šealtielov, Nerijev,"},{"v":28,"t":"Malkijev, Adijev, Kosamov, Elmadamov, Erov,"},{"v":29,"t":"Jošuin, Eliezerov, Jorimov, Matatov, Levijev,"},{"v":30,"t":"Šimunov, Judin, Josipov, Jonamov, Elijakimov,"},{"v":31,"t":"Melejin, Menin, Matatin, Natanov, Davidov,"},{"v":32,"t":"Jišajev, Obedov, Boazov, Salin, Nahšonov,"},{"v":33,"t":"Aminadabov, Adminov, Arnijev, Hesronov, Peresov, Judin,"},{"v":34,"t":"Jakovljev, Izakov, Abrahamov, Terahov, Nahorov,"},{"v":35,"t":"Serugov, Reuov, Pelegov, Eberov, Šelahov,"},{"v":36,"t":"Kenanov, Arpakšadov, Šemov, Noin, Lamekov,"},{"v":37,"t":"Metušalahov, Henokov, Jeredov, Mahalalelov, Kenanov,"},{"v":38,"t":"Enošev, Šetov, Adamov, Božji."}]},"4":{"fa":[{"v":1,"t":"اما عیسی پر از روح‌القدس بوده، از اردن مراجعت کرد و روح او را به بیابان برد."},{"v":2,"t":"ومدت چهل روز ابلیس او را تجربه می‌نمود و درآن ایام چیزی نخورد. چون تمام شد، آخر گرسنه گردید."},{"v":3,"t":"و ابلیس بدو گفت: «اگر پسر خدا هستی، این سنگ را بگو تا نان گردد.»"},{"v":4,"t":"عیسی در جواب وی گفت: «مکتوب است که انسان به نان فقط زیست نمی کند، بلکه به هر کلمه خدا.»"},{"v":5,"t":"پس ابلیس او رابه کوهی بلند برده، تمامی ممالک جهان را درلحظه‌ای بدو نشان داد."},{"v":6,"t":"و ابلیس بدو گفت: «جمیع این قدرت و حشمت آنها را به تو می‌دهم، زیرا که به من سپرده شده است و به هر‌که می‌خواهم می‌بخشم."},{"v":7,"t":"پس اگر تو پیش من سجده کنی، همه از آن تو خواهد شد.»"},{"v":8,"t":"عیسی در جواب او گفت: «ای شیطان، مکتوب است، خداوند خدای خود را پرستش کن و غیر او راعبادت منما.»"},{"v":9,"t":"پس او را به اورشلیم برده، برکنگره هیکل قرار داد و بدو گفت: «اگر پسر خداهستی، خود را از اینجا به زیر انداز."},{"v":10,"t":"زیرامکتوب است که فرشتگان خود را درباره تو حکم فرماید تا تو را محافظت کنند."},{"v":11,"t":"و تو را به‌دستهای خود بردارند، مبادا پایت به سنگی خورد.»"},{"v":12,"t":"عیسی در جواب وی گفت که «گفته شده است، خداوند خدای خود را تجربه مکن.»"},{"v":13,"t":"و چون ابلیس جمیع تجربه را به اتمام رسانید، تا مدتی از او جدا شد."},{"v":14,"t":"و عیسی به قوت روح، به جلیل برگشت وخبر او در تمامی آن نواحی شهرت یافت."},{"v":15,"t":"و اودر کنایس ایشان تعلیم می‌داد و همه او را تعظیم می‌کردند."},{"v":16,"t":"و به ناصره جایی که پرورش یافته بود، رسید و بحسب دستور خود در روز سبت به کنیسه درآمده، برای تلاوت برخاست."},{"v":17,"t":"آنگاه صحیفه اشعیا نبی را بدو دادند و چون کتاب راگشود، موضعی را یافت که مکتوب است"},{"v":18,"t":"«روح خداوند بر من است، زیرا که مرا مسح کرد تا فقیران را بشارت دهم و مرا فرستاد، تاشکسته دلان را شفا بخشم و اسیران را به رستگاری و کوران را به بینایی، موعظه کنم و تاکوبیدگان را، آزاد سازم،"},{"v":19,"t":"و از سال پسندیده خداوند موعظه کنم.»"},{"v":20,"t":"پس کتاب را به هم پیچیده، به خادم سپرد وبنشست و چشمان همه اهل کنیسه بر وی دوخته می‌بود."},{"v":21,"t":"آنگاه بدیشان شروع به گفتن کرد که «امروز این نوشته در گوشهای شما تمام شد.»"},{"v":22,"t":"و همه بر وی شهادت دادند و از سخنان فیض آمیزی که از دهانش صادر می‌شد، تعجب نموده، گفتند: «مگر این پسر یوسف نیست؟»"},{"v":23,"t":"بدیشان گفت: «هرآینه این مثل را به من خواهیدگفت، ای طبیب خود را شفا بده. آنچه شنیده‌ایم که در کفرناحوم از تو صادر شد، اینجا نیز در وطن خویش بنما.»"},{"v":24,"t":"و گفت: «هرآینه به شمامی گویم که هیچ نبی در وطن خویش مقبول نباشد."},{"v":25,"t":"و به تحقیق شما را می‌گویم که بسا بیوه‌زنان در اسرائیل بودند، در ایام الیاس، وقتی که آسمان مدت سه سال و شش ماه بسته ماند، چنانکه قحطی عظیم در تمامی زمین پدید آمد،"},{"v":26,"t":"و الیاس نزد هیچ کدام از ایشان فرستاده نشد، مگر نزد بیوه‌زنی در صرفه صیدون."},{"v":27,"t":"و بساابرصان در اسرائیل بودند، در ایام الیشع نبی واحدی از ایشان طاهر نگشت، جز نعمان سریانی.»"},{"v":28,"t":"پس تمام اهل کنیسه چون این سخنان راشنیدند، پر از خشم گشتند."},{"v":29,"t":"و برخاسته او را ازشهر بیرون کردند و بر قله کوهی که قریه ایشان برآن بنا شده بود بردند، تا او را به زیر افکنند."},{"v":30,"t":"ولی از میان ایشان گذشته، برفت."},{"v":31,"t":"و به کفرناحوم شهری از جلیل فرود شده، در روزهای سبت، ایشان را تعلیم می‌داد."},{"v":32,"t":"و ازتعلیم او در حیرت افتادند، زیرا که کلام او باقدرت می‌بود."},{"v":33,"t":"و در کنیسه مردی بود، که روح دیو خبیث داشت و به آواز بلند فریادکنان می‌گفت:"},{"v":34,"t":"«آه‌ای عیسی ناصری، ما را با تو چه‌کار است، آیا آمده‌ای تا ما را هلاک سازی؟ تو را می شناسم کیستی، ای قدوس خدا.»"},{"v":35,"t":"پس عیسی او را نهیب داده، فرمود: «خاموش باش و ازوی بیرون آی.» در ساعت دیو او را در میان انداخته، از او بیرون شد و هیچ آسیبی بدونرسانید."},{"v":36,"t":"پس حیرت بر همه ایشان مستولی گشت و یکدیگر را مخاطب ساخته، گفتند: «این چه سخن است که این شخص با قدرت و قوت، ارواح پلید را امر می‌کند و بیرون می‌آیند!»"},{"v":37,"t":"وشهرت او در هر موضعی از آن حوالی، پهن شد."},{"v":38,"t":"و از کنیسه برخاسته، به خانه شمعون درآمد. و مادر‌زن شمعون را تب شدیدی عارض شده بود، برای او از وی التماس کردند."},{"v":39,"t":"پس برسر وی آمده، تب را نهیب داده، تب از او زایل شد. در ساعت برخاسته، به خدمتگذاری ایشان مشغول شد."},{"v":40,"t":"و چون آفتاب غروب می‌کرد، همه آنانی که اشخاص مبتلا به انواع مرضها داشتند، ایشان را نزد وی آوردند و به هر یکی از ایشان دست گذارده، شفا داد."},{"v":41,"t":"و دیوها نیز از بسیاری بیرون می‌رفتند و صیحه زنان می‌گفتند که «تو مسیح پسرخدا هستی.» ولی ایشان را قدغن کرده، نگذاشت که حرف زنند، زیرا که دانستند او مسیح است."},{"v":42,"t":"و چون روز شد، روانه شده به مکانی ویران رفت و گروهی کثیر در جستجوی او آمده، نزدش رسیدند و او را باز می‌داشتند که از نزد ایشان نرود."},{"v":43,"t":"به ایشان گفت: «مرا لازم است که به شهرهای دیگر نیز به ملکوت خدا بشارت دهم، زیرا که برای همین کار فرستاده شده‌ام.»"},{"v":44,"t":"پس در کنایس جلیل موعظه می‌نمود."}],"en":[{"v":1,"t":"Jesus, full of the Holy Spirit, returned from the Jordan and was led by the Spirit into the wilderness"},{"v":2,"t":"for forty days, being tempted by the devil. He ate nothing in those days. Afterward, when they were completed, he was hungry."},{"v":3,"t":"The devil said to him, “If you are the Son of God, command this stone to become bread.”"},{"v":4,"t":"Jesus answered him, saying, “It is written, ‘Man shall not live by bread alone, but by every word of God.’”"},{"v":5,"t":"The devil, leading him up on a high mountain, showed him all the kingdoms of the world in a moment of time."},{"v":6,"t":"The devil said to him, “I will give you all this authority and their glory, for it has been delivered to me, and I give it to whomever I want."},{"v":7,"t":"If you therefore will worship before me, it will all be yours.”"},{"v":8,"t":"Jesus answered him, “Get behind me, Satan! For it is written, ‘You shall worship the Lord your God, and you shall serve him only.’”"},{"v":9,"t":"He led him to Jerusalem and set him on the pinnacle of the temple, and said to him, “If you are the Son of God, cast yourself down from here,"},{"v":10,"t":"for it is written, ‘He will put his angels in charge of you, to guard you;’"},{"v":11,"t":"and, ‘On their hands they will bear you up, lest perhaps you dash your foot against a stone.’”"},{"v":12,"t":"Jesus answering, said to him, “It has been said, ‘You shall not tempt the Lord your God.’”"},{"v":13,"t":"When the devil had completed every temptation, he departed from him until another time."},{"v":14,"t":"Jesus returned in the power of the Spirit into Galilee, and news about him spread through all the surrounding area."},{"v":15,"t":"He taught in their synagogues, being glorified by all."},{"v":16,"t":"He came to Nazareth, where he had been brought up. He entered, as was his custom, into the synagogue on the Sabbath day, and stood up to read."},{"v":17,"t":"The book of the prophet Isaiah was handed to him. He opened the book, and found the place where it was written,"},{"v":18,"t":"“The Spirit of the Lord is on me, because he has anointed me to preach good news to the poor. He has sent me to heal the broken hearted, to proclaim release to the captives, recovering of sight to the blind, to deliver those who are crushed,"},{"v":19,"t":"and to proclaim the acceptable year of the Lord.”"},{"v":20,"t":"He closed the book, gave it back to the attendant, and sat down. The eyes of all in the synagogue were fastened on him."},{"v":21,"t":"He began to tell them, “Today, this Scripture has been fulfilled in your hearing.”"},{"v":22,"t":"All testified about him and wondered at the gracious words which proceeded out of his mouth; and they said, “Isn’t this Joseph’s son?”"},{"v":23,"t":"He said to them, “Doubtless you will tell me this proverb, ‘Physician, heal yourself! Whatever we have heard done at Capernaum, do also here in your hometown.’”"},{"v":24,"t":"He said, “Most certainly I tell you, no prophet is acceptable in his hometown."},{"v":25,"t":"But truly I tell you, there were many widows in Israel in the days of Elijah, when the sky was shut up three years and six months, when a great famine came over all the land."},{"v":26,"t":"Elijah was sent to none of them, except to Zarephath, in the land of Sidon, to a woman who was a widow."},{"v":27,"t":"There were many lepers in Israel in the time of Elisha the prophet, yet not one of them was cleansed, except Naaman, the Syrian.”"},{"v":28,"t":"They were all filled with wrath in the synagogue as they heard these things."},{"v":29,"t":"They rose up, threw him out of the city, and led him to the brow of the hill that their city was built on, that they might throw him off the cliff."},{"v":30,"t":"But he, passing through the middle of them, went his way."},{"v":31,"t":"He came down to Capernaum, a city of Galilee. He was teaching them on the Sabbath day,"},{"v":32,"t":"and they were astonished at his teaching, for his word was with authority."},{"v":33,"t":"In the synagogue there was a man who had a spirit of an unclean demon; and he cried out with a loud voice,"},{"v":34,"t":"saying, “Ah! what have we to do with you, Jesus of Nazareth? Have you come to destroy us? I know who you are: the Holy One of God!”"},{"v":35,"t":"Jesus rebuked him, saying, “Be silent and come out of him!” When the demon had thrown him down in the middle of them, he came out of him, having done him no harm."},{"v":36,"t":"Amazement came on all and they spoke together, one with another, saying, “What is this word? For with authority and power he commands the unclean spirits, and they come out!”"},{"v":37,"t":"News about him went out into every place of the surrounding region."},{"v":38,"t":"He rose up from the synagogue and entered into Simon’s house. Simon’s mother-in-law was afflicted with a great fever, and they begged him to help her."},{"v":39,"t":"He stood over her and rebuked the fever, and it left her. Immediately she rose up and served them."},{"v":40,"t":"When the sun was setting, all those who had any sick with various diseases brought them to him; and he laid his hands on every one of them, and healed them."},{"v":41,"t":"Demons also came out of many, crying out and saying, “You are the Christ, the Son of God!” Rebuking them, he didn’t allow them to speak, because they knew that he was the Christ."},{"v":42,"t":"When it was day, he departed and went into an uninhabited place and the multitudes looked for him, and came to him, and held on to him, so that he wouldn’t go away from them."},{"v":43,"t":"But he said to them, “I must preach the good news of God’s Kingdom to the other cities also. For this reason I have been sent.”"},{"v":44,"t":"He was preaching in the synagogues of Galilee."}],"hr":[{"v":1,"t":"Isus se, pun Duha Svetoga, vratio s Jordana i Duh ga četrdeset dana vodio pustinjom,"},{"v":2,"t":"gdje ga je iskušavao đavao. Tih dana nije ništa jeo, te kad oni istekoše, ogladnje."},{"v":3,"t":"A đavao mu reče: “Ako si Sin Božji, reci ovom kamenu da postane kruhom.”"},{"v":4,"t":"Isus mu odgovori: “Pisano je: Ne živi čovjek samo o kruhu.”"},{"v":5,"t":"I povede ga đavao na visoko, pokaza mu odjednom sva kraljevstva zemlje"},{"v":6,"t":"i reče mu: “Tebi ću dati svu ovu vlast i slavu njihovu jer meni je dana i komu hoću, dajem je."},{"v":7,"t":"Ako se dakle pokloniš preda mnom, sve je tvoje.”"},{"v":8,"t":"Isus mu odgovori: “Pisano je: Klanjaj se Gospodinu, Bogu svomu, i njemu jedinomu služi!”"},{"v":9,"t":"Povede ga u Jeruzalem i postavi na vrh Hrama i reče mu: “Ako si Sin Božji, baci se odavde dolje!"},{"v":10,"t":"Ta pisamo je: Anđelima će svojim zapovjediti za tebe da te čuvaju."},{"v":11,"t":"I: Na rukama će te nositi da se gdje nogom ne spotakneš o kamen.”"},{"v":12,"t":"Odgovori mu Isus: “Rečeno je: Ne iskušavaj Gospodina, Boga svojega!”"},{"v":13,"t":"Pošto iscrpi sve kušnje, đavao se udalji od njega do druge prilike."},{"v":14,"t":"A Isus se u snazi Duha vrati u Galileju te glas o njemu puče po svoj okolici."},{"v":15,"t":"I slavljen od sviju, naučavaše po njihovim sinagogama."},{"v":16,"t":"I dođe u Nazaret, gdje bijaše othranjen. I uđe po svom običaju na dan subotni u sinagogu te ustane čitati."},{"v":17,"t":"Pruže mu Knjigu proroka Izaije. On razvije knjigu i nađe mjesto gdje stoji napisano:"},{"v":18,"t":"Duh Gospodnji na meni je jer me pomaza! On me posla blagovjesnikom biti siromasima, proglasiti sužnjima oslobođenje, vid slijepima, na slobodu pustiti potlačene,"},{"v":19,"t":"proglasiti godinu milosti Gospodnje."},{"v":20,"t":"Tada savi knjigu, vrati je poslužitelju i sjede. Oči sviju u sinagogi bijahu uprte u njega."},{"v":21,"t":"On im progovori: “Danas se ispunilo ovo Pismo što vam još odzvanja u ušima.”"},{"v":22,"t":"I svi su mu povlađivali i divili se milini riječi koje su tekle iz njegovih usta. Govorahu: “Nije li ovo sin Josipov?”"},{"v":23,"t":"A on im reče: “Zacijelo ćete mi reći onu prispodobu: Liječniče, izliječi sam sebe! Što smo čuli da se dogodilo u Kafarnaumu, učini i ovdje, u svom zavičaju.”"},{"v":24,"t":"I nastavi: “Zaista, kažem vam, nijedan prorok nije dobro došao u svom zavičaju."},{"v":25,"t":"Uistinu, kažem vam, mnogo bijaše udovica u Izraelu u dane Ilijine kad se na tri godine i šest mjeseci zatvorilo nebo pa zavladala velika glad po svoj zemlji."},{"v":26,"t":"I ni k jednoj od njih nije bio poslan Ilija doli k ženi udovici u Sarfati sidonskoj."},{"v":27,"t":"I mnogo bijaše gubavaca u Izraelu za proroka Elizeja. I nijedan se od njih ne očisti doli Naaman Sirac.”"},{"v":28,"t":"Čuvši to, svi se u sinagogi napune gnjevom,"},{"v":29,"t":"ustanu, izbace ga iz grada i odvedu na rub brijega na kojem je sagrađen njihov grad da ga strmoglave."},{"v":30,"t":"No on prođe između njih i ode."},{"v":31,"t":"I siđe u Kafarnaum, grad galilejski. I poučavaše ih subotom"},{"v":32,"t":"te bijahu zaneseni njegovim naukom jer silna bijaše riječ njegova."},{"v":33,"t":"A zatekao se u sinagogi čovjek s duhom nečistoga đavla. On povika u sav glas:"},{"v":34,"t":"“Hej, što ti imaš s nama, Isuse Nazarećanine? Došao si da nas uništiš! Znam ja tko si ti: Svetac Božji.”"},{"v":35,"t":"Isus mu zaprijeti: “Umukni i iziđi iz njega!” Nato đavao čovjeka obori u sredinu te iziđe iz njega ne naudiv mu ništa."},{"v":36,"t":"I nasta opće zaprepaštenje te se među sobom razgovarahu: “Kakve li riječi! S vlašću i snagom zapovijeda nečistim dusima te izlaze!”"},{"v":37,"t":"I glas se o njemu širio po svim okolnim mjestima."},{"v":38,"t":"Ustavši iz sinagoge, uđe u kuću Šimunovu. A Šimunovu je punicu mučila velika ognjica. I zamole ga za nju."},{"v":39,"t":"On se nadvi nad nju, zaprijeti ognjici i ona je pusti. I odmah ustade i posluživaše im."},{"v":40,"t":"O zalazu sunca svi koji su imali bolesnike od raznih bolesti dovedoše ih k njemu. A on bi na svakoga od njih stavljao ruke i ozdravljao ih."},{"v":41,"t":"A iz mnogih su izlazili i zlodusi vičući: “Ti si Sin Božji!” On im se prijetio i nije im dao govoriti jer su znali da je on Krist."},{"v":42,"t":"Kad osvanu dan, iziđe i pođe na samotno mjesto. I mnoštvo ga tražilo. Dođoše k njemu i zadržavahu ga da ne ode od njih."},{"v":43,"t":"A on im reče: “I drugim gradovima treba da navješćujem evanđelje o kraljevstvu Božjem. Jer za to sam poslan.”"},{"v":44,"t":"I naučavaše po sinagogama judejskim."}]},"5":{"fa":[{"v":1,"t":"و هنگامی که گروهی بر وی ازدحام می نمودند تا کلام خدا را بشنوند، او به کناردریاچه جنیسارت ایستاده بود."},{"v":2,"t":"و دو زورق رادر کنار دریاچه ایستاده دید که صیادان از آنهابیرون آمده، دامهای خود را شست و شومی نمودند."},{"v":3,"t":"پس به یکی از آن دو زورق که مال شمعون بود سوار شده، از او درخواست نمود که از خشکی اندکی دور ببرد. پس در زورق نشسته، مردم را تعلیم می‌داد."},{"v":4,"t":"و چون از سخن‌گفتن فارغ شد، به شمعون گفت: «به میانه دریاچه بران و دامهای خود رابرای شکار بیندازید.»"},{"v":5,"t":"شمعون در جواب وی گفت: «ای استاد، تمام شب را رنج برده چیزی نگرفتیم، لیکن به حکم تو، دام را خواهیم انداخت.»"},{"v":6,"t":"و چون چنین کردند، مقداری کثیر ازماهی صید کردند، چنانکه نزدیک بود دام ایشان گسسته شود."},{"v":7,"t":"و به رفقای خود که در زورق دیگربودند اشاره کردند که آمده ایشان را امداد کنند. پس آمده هر دو زورق را پر کردند بقسمی که نزدیک بود غرق شوند."},{"v":8,"t":"شمعون پطرس چون این را بدید، بر پایهای عیسی افتاده، گفت: «ای خداوند از من دور شو زیرا مردی گناهکارم.»"},{"v":9,"t":"چونکه به‌سبب صیدماهی که کرده بودند، دهشت بر او و همه رفقای وی مستولی شده بود."},{"v":10,"t":"و هم چنین نیز بریعقوب و یوحنا پسران زبدی که شریک شمعون بودند. عیسی به شمعون گفت: «مترس. پس از این مردم را صید خواهی کرد.»"},{"v":11,"t":"پس چون زورقهارا به کنار آوردند همه را ترک کرده، از عقب اوروانه شدند."},{"v":12,"t":"و چون او در شهری از شهرها بود ناگاه مردی پر از برص آمده، چون عیسی را بدید، به روی در‌افتاد و از او درخواست کرده، گفت: «خداوندا، اگر خواهی می‌توانی مرا طاهرسازی.»"},{"v":13,"t":"پس او دست آورده، وی را لمس نمود و گفت: «می‌خواهم. طاهر شو.» که فور برص از او زایل شد."},{"v":14,"t":"و او را قدغن کرد که «هیچ‌کس را خبر مده، بلکه رفته خود را به کاهن بنما و هدیه‌ای بجهت طهارت خود، بطوری که موسی فرموده است، بگذران تا بجهت ایشان شهادتی شود.»"},{"v":15,"t":"لیکن خبر او بیشتر شهرت یافت و گروهی بسیار جمع شدند تا کلام او رابشنوند و از مرضهای خود شفا یابند،"},{"v":16,"t":"و او به ویرانه‌ها عزلت جسته، به عبادت مشغول شد."},{"v":17,"t":"روزی از روزها واقع شد که او تعلیم می‌دادو فریسیان و فقها که از همه بلدان جلیل و یهودیه و اورشلیم آمده، نشسته بودند وقوت خداوندبرای شفای ایشان صادر می‌شد،"},{"v":18,"t":"که ناگاه چندنفر شخصی مفلوج را بر بستری آوردند ومی خواستند او را داخل کنند تا پیش روی وی بگذارند."},{"v":19,"t":"و چون به‌سبب انبوهی مردم راهی نیافتند که او را به خانه درآورند بر پشت بام رفته، او را با تختش از میان سفالها در وسط پیش عیسی گذاردند."},{"v":20,"t":"چون او ایمان ایشان را دید، به وی گفت: «ای مرد، گناهان تو آمرزیده شد.»"},{"v":21,"t":"آنگاه کاتبان و فریسیان در خاطر خود تفکرنموده، گفتن گرفتند: «این کیست که کفر می‌گوید. جز خدا و بس کیست که بتواند گناهان رابیامرزد؟»"},{"v":22,"t":"عیسی افکار ایشان را درک نموده، در جواب ایشان گفت: «چرا در خاطر خود تفکرمی کنید؟"},{"v":23,"t":"کدام سهلتر است، گفتن اینکه گناهان تو آمرزیده شد، یا گفتن اینکه برخیز و بخرام؟"},{"v":24,"t":"لیکن تا بدانید که پسر انسان را استطاعت آمرزیدن گناهان بر روی زمین هست، مفلوج راگفت، تو را می‌گویم برخیز و بستر خود رابرداشته، به خانه خود برو.»"},{"v":25,"t":"در ساعت برخاسته، پیش ایشان آنچه بر آن خوابیده بودبرداشت و به خانه خود خدا را حمدکنان روانه شد."},{"v":26,"t":"و حیرت همه را فرو گرفت و خدا راتمجید می‌نمودند و خوف بر ایشان مستولی شده، گفتند: «امروز چیزهای عجیب دیدیم.»"},{"v":27,"t":"از آن پس بیرون رفته، باجگیری را که لاوی نام داشت، بر باجگاه نشسته دید. او را گفت: «از عقب من بیا.»"},{"v":28,"t":"در حال همه‌چیز را ترک کرده، برخاست و در عقب وی روانه شد."},{"v":29,"t":"و لاوی ضیافتی بزرگ در خانه خود برای او کرد و جمعی بسیار از باجگیران و دیگران با ایشان نشستند."},{"v":30,"t":"اما کاتبان ایشان و فریسیان همهمه نموده، به شاگردان او گفتند: «برای چه با باجگیران وگناهکاران اکل و شرب می‌کنید؟»"},{"v":31,"t":"عیسی درجواب ایشان گفت: «تندرستان احتیاج به طبیب ندارند بلکه مریضان."},{"v":32,"t":"و نیامده‌ام تا عادلان بلکه تا عاصیان را به توبه بخوانم.»"},{"v":33,"t":"پس به وی گفتند: «از چه سبب شاگردان یحیی روزه بسیار می‌دارند و نماز می‌خوانند وهمچنین شاگردان فریسیان نیز، لیکن شاگردان تواکل و شرب می‌کنند.»"},{"v":34,"t":"بدیشان گفت: «آیامی توانید پسران خانه عروسی را مادامی که دامادبا ایشان است روزه‌دار سازید؟"},{"v":35,"t":"بلکه ایامی می‌آید که داماد از ایشان گرفته شود، آنگاه در آن روزها روزه خواهند داشت.»"},{"v":36,"t":"و مثلی برای ایشان آورد که «هیچ‌کس پارچه‌ای از جامه نو را بر جامه کهنه وصله نمی کند والا آن نو را پاره کند و وصله‌ای که از نوگرفته شد نیز در خور آن کهنه نبود."},{"v":37,"t":"و هیچ‌کس شراب نو را در مشکهای کهنه نمی ریزد والاشراب نو، مشکها را پاره می‌کند و خودش ریخته و مشکها تباه می‌گردد."},{"v":38,"t":"بلکه شراب نو را درمشکهای نو باید ریخت تا هر دو محفوظ بماند."},{"v":39,"t":"و کسی نیست که چون شراب کهنه را نوشیده فی الفور نو را طلب کند، زیرا می‌گوید کهنه بهتراست.»"}],"en":[{"v":1,"t":"Now while the multitude pressed on him and heard the word of God, he was standing by the lake of Gennesaret."},{"v":2,"t":"He saw two boats standing by the lake, but the fishermen had gone out of them and were washing their nets."},{"v":3,"t":"He entered into one of the boats, which was Simon’s, and asked him to put out a little from the land. He sat down and taught the multitudes from the boat."},{"v":4,"t":"When he had finished speaking, he said to Simon, “Put out into the deep and let down your nets for a catch.”"},{"v":5,"t":"Simon answered him, “Master, we worked all night and caught nothing; but at your word I will let down the net.”"},{"v":6,"t":"When they had done this, they caught a great multitude of fish, and their net was breaking."},{"v":7,"t":"They beckoned to their partners in the other boat, that they should come and help them. They came and filled both boats, so that they began to sink."},{"v":8,"t":"But Simon Peter, when he saw it, fell down at Jesus’ knees, saying, “Depart from me, for I am a sinful man, Lord.”"},{"v":9,"t":"For he was amazed, and all who were with him, at the catch of fish which they had caught;"},{"v":10,"t":"and so also were James and John, sons of Zebedee, who were partners with Simon. Jesus said to Simon, “Don’t be afraid. From now on you will be catching people alive.”"},{"v":11,"t":"When they had brought their boats to land, they left everything, and followed him."},{"v":12,"t":"While he was in one of the cities, behold, there was a man full of leprosy. When he saw Jesus, he fell on his face and begged him, saying, “Lord, if you want to, you can make me clean.”"},{"v":13,"t":"He stretched out his hand and touched him, saying, “I want to. Be made clean.” Immediately the leprosy left him."},{"v":14,"t":"He commanded him to tell no one, “But go your way and show yourself to the priest, and offer for your cleansing according to what Moses commanded, for a testimony to them.”"},{"v":15,"t":"But the report concerning him spread much more, and great multitudes came together to hear and to be healed by him of their infirmities."},{"v":16,"t":"But he withdrew himself into the desert and prayed."},{"v":17,"t":"On one of those days, he was teaching; and there were Pharisees and teachers of the law sitting by who had come out of every village of Galilee, Judea, and Jerusalem. The power of the Lord was with him to heal them."},{"v":18,"t":"Behold, men brought a paralyzed man on a cot, and they sought to bring him in to lay before Jesus."},{"v":19,"t":"Not finding a way to bring him in because of the multitude, they went up to the housetop and let him down through the tiles with his cot into the middle before Jesus."},{"v":20,"t":"Seeing their faith, he said to him, “Man, your sins are forgiven you.”"},{"v":21,"t":"The scribes and the Pharisees began to reason, saying, “Who is this who speaks blasphemies? Who can forgive sins, but God alone?”"},{"v":22,"t":"But Jesus, perceiving their thoughts, answered them, “Why are you reasoning so in your hearts?"},{"v":23,"t":"Which is easier to say, ‘Your sins are forgiven you,’ or to say, ‘Arise and walk’?"},{"v":24,"t":"But that you may know that the Son of Man has authority on earth to forgive sins,” he said to the paralyzed man, “I tell you, arise, take up your cot, and go to your house.”"},{"v":25,"t":"Immediately he rose up before them, and took up that which he was laying on, and departed to his house, glorifying God."},{"v":26,"t":"Amazement took hold on all, and they glorified God. They were filled with fear, saying, “We have seen strange things today.”"},{"v":27,"t":"After these things he went out and saw a tax collector named Levi sitting at the tax office, and said to him, “Follow me!”"},{"v":28,"t":"He left everything, and rose up and followed him."},{"v":29,"t":"Levi made a great feast for him in his house. There was a great crowd of tax collectors and others who were reclining with them."},{"v":30,"t":"Their scribes and the Pharisees murmured against his disciples, saying, “Why do you eat and drink with the tax collectors and sinners?”"},{"v":31,"t":"Jesus answered them, “Those who are healthy have no need for a physician, but those who are sick do."},{"v":32,"t":"I have not come to call the righteous, but sinners, to repentance.”"},{"v":33,"t":"They said to him, “Why do John’s disciples often fast and pray, likewise also the disciples of the Pharisees, but yours eat and drink?”"},{"v":34,"t":"He said to them, “Can you make the friends of the bridegroom fast while the bridegroom is with them?"},{"v":35,"t":"But the days will come when the bridegroom will be taken away from them. Then they will fast in those days.”"},{"v":36,"t":"He also told a parable to them. “No one puts a piece from a new garment on an old garment, or else he will tear the new, and also the piece from the new will not match the old."},{"v":37,"t":"No one puts new wine into old wineskins, or else the new wine will burst the skins, and it will be spilled and the skins will be destroyed."},{"v":38,"t":"But new wine must be put into fresh wineskins, and both are preserved."},{"v":39,"t":"No man having drunk old wine immediately desires new, for he says, ‘The old is better.’”"}],"hr":[{"v":1,"t":"Dok se jednom oko njega gurao narod da čuje riječ Božju, stajaše on pokraj Genezaretskog jezera."},{"v":2,"t":"Spazi dvije lađe gdje stoje uz obalu; ribari bili izašli iz njih i ispirali mreže."},{"v":3,"t":"Uđe u jednu od tih lađa; bila je Šimunova pa zamoli Šimuna da malo otisne od kraja. Sjedne te iz lađe poučavaše mnoštvo."},{"v":4,"t":"Kada dovrši pouku, reče Šimunu: “Izvezi na pučinu i bacite mreže za lov.”"},{"v":5,"t":"Odgovori Šimun: “Učitelju, svu smo se noć trudili i ništa ne ulovismo, ali na tvoju riječ bacit ću mreže.”"},{"v":6,"t":"Učiniše tako te uhvatiše veoma mnogo riba; mreže im se gotovo razdirale."},{"v":7,"t":"Mahnuše drugovima na drugoj lađi da im dođu pomoći. Oni dođoše i napuniše obje lađe, umalo im ne potonuše."},{"v":8,"t":"Vidjevši to, Šimun Petar pade do nogu Isusovih govoreći: “Idi od mene! Grešan sam čovjek, Gospodine!”"},{"v":9,"t":"Zbog lovine riba što ih uloviše bijaše se zapanjio on i svi koji bijahu s njime,"},{"v":10,"t":"a tako i Jakov i Ivan, Zebedejevi sinovi, drugovi Šimunovi. Isus reče Šimunu: “Ne boj se! Odsada ćeš loviti ljude!”"},{"v":11,"t":"Oni izvukoše lađe na kopno, ostaviše sve i pođoše za njim."},{"v":12,"t":"I dok bijaše u jednom gradu, gle čovjeka puna gube! Ugledavši Isusa, padne ničice i zamoli ga: “Gospodine, ako hoćeš, možeš me očistiti.”"},{"v":13,"t":"Isus pruži ruku i dotakne ga se govoreći: “Hoću, očisti se!” I odmah nesta gube s njega."},{"v":14,"t":"I zapovjedi mu: “Nikome ni riječi, nego otiđi, pokaži se svećeniku i prinesi za svoje očišćenje kako propisa Mojsije, njima za svjedočanstvo.”"},{"v":15,"t":"Glas se o njemu sve više širio i silan svijet grnuo k njemu da ga sluša i da ozdravi od svojih bolesti."},{"v":16,"t":"A on se sklanjao na samotna mjesta da moli."},{"v":17,"t":"I jednog je dana on naučavao. A sjeđahu ondje farizeji i učitelji Zakona koji bijahu došli iz svih galilejskih i judejskih sela i Jeruzalema. A sila ga je Gospodnja nukala da liječi."},{"v":18,"t":"I gle, ljudi doniješe na nosiljci čovjeka koji bijaše uzet. Tražili su da ga unesu i stave preda nj."},{"v":19,"t":"Budući da zbog mnoštva nisu našli kuda bi ga unijeli, popnu se na krov te ga između crepova s nosiljkom spuste u sredinu pred Isusa."},{"v":20,"t":"Vidjevši njihovu vjeru reče on: “Čovječe, otpušteni su ti grijesi!”"},{"v":21,"t":"Pismoznanci i farizeji počeše mudrovati: “Tko je ovaj što huli? Tko može grijehe otpuštati doli Bog jedini?”"},{"v":22,"t":"Proniknuvši njihovo mudrovanje, upita ih Isus: “Što mudrujete u sebi?"},{"v":23,"t":"Što je lakše? Reći: 'Otpušteni su ti grijesi' ili reći: 'Ustani i hodi?'"},{"v":24,"t":"Ali da znate: Vlastan je Sin Čovječji na zemlji otpuštati grijehe!” I reče uzetomu: “Tebi zapovijedam: ustani, uzmi nosiljku i idi kući!”"},{"v":25,"t":"I on odmah usta pred njima, uze na čemu ležaše i ode kući slaveći Boga."},{"v":26,"t":"A sve obuze zanos te su slavili Boga i puni straha govorili: “Danas vidjesmo nešto neviđeno!”"},{"v":27,"t":"Nakon toga iziđe i ugleda carinika imenom Levija gdje sjedi u carinarnici. I reče mu: “Pođi za mnom!”"},{"v":28,"t":"On sve ostavi, usta i pođe za njim."},{"v":29,"t":"I Levi mu u svojoj kući priredi veliku gozbu. A s njime bijaše za stolom veliko mnoštvo carinika i drugih."},{"v":30,"t":"Farizeji i pismoznanci njihovi negodovahu i govorahu njegovim učenicima: “Zašto s carinicima i grešnicima jedete i pijete?”"},{"v":31,"t":"Isus im odgovori: “Ne treba zdravima liječnika, nego bolesnima."},{"v":32,"t":"Nisam došao zvati pravedne, nego grešnike na obraćenje.”"},{"v":33,"t":"A oni mu rekoše: “Učenici Ivanovi, a tako i farizejski, počesto poste i obavljaju molitve, tvoji pak jedu i piju.”"},{"v":34,"t":"Reče im Isus: “Ne možete svatove prisiliti da poste dok je zaručnik s njima."},{"v":35,"t":"Doći će već dani: kad im se ugrabi zaručnik, tada će postiti, u one dane!”"},{"v":36,"t":"A kazivao im je i prispodobu: “Nitko neće otparati krpe s novog odijela da je stavi na staro odijelo. Inače će i novo rasparati, a starom neće pristajati krpa s novoga.”"},{"v":37,"t":"“I nitko ne ulijeva novo vino u stare mješine. Inače će novo vino proderati mješine pa će se i ono proliti i mješine će propasti."},{"v":38,"t":"Nego, novo vino neka se ulijeva u nove mješine!”"},{"v":39,"t":"“I nitko pijuć staro, ne zaželi novoga. Ta veli se: 'Valja staro!'”"}]},"6":{"fa":[{"v":1,"t":"و واقع شد در سبت دوم اولین که او از میان کشت زارها می‌گذشت و شاگردانش خوشه‌ها می‌چیدند و به کف مالیده می‌خوردند."},{"v":2,"t":"و بعضی از فریسیان بدیشان گفتند: «چرا کاری می‌کنید که کردن آن در سبت جایز نیست.»"},{"v":3,"t":"عیسی در جواب ایشان گفت: «آیا نخوانده ایدآنچه داود و رفقایش کردند در وقتی که گرسنه بودند،"},{"v":4,"t":"که چگونه به خانه خدا درآمده نان تقدمه را گرفته بخورد و به رفقای خود نیز داد که خوردن آن جز به کهنه روا نیست.»"},{"v":5,"t":"پس بدیشان گفت: «پسر انسان مالک روز سبت نیز هست.»"},{"v":6,"t":"و در سبت دیگر به کنیسه درآمده تعلیم می‌داد و در آنجا مردی بود که دست راستش خشک بود."},{"v":7,"t":"و کاتبان و فریسیان چشم بر اومی داشتند که شاید در سبت شفا دهد تا شکایتی بر او یابند."},{"v":8,"t":"او خیالات ایشان را درک نموده، بدان مرد دست خشک گفت: «برخیز و در میان بایست.» در حال برخاسته بایستاد."},{"v":9,"t":"عیسی بدیشان گفت: «از شما چیزی می‌پرسم که در روزسبت کدام رواست، نیکویی‌کردن یا بدی، رهانیدن جان یا هلاک کردن؟»"},{"v":10,"t":"پس چشم خود را بر جمیع ایشان گردانیده، بدو گفت: «دست خود را دراز کن.» او چنان کرد و فور دستش مثل دست دیگر صحیح گشت."},{"v":11,"t":"اما ایشان ازحماقت پر گشته به یکدیگر می‌گفتند که «باعیسی چه کنیم؟»"},{"v":12,"t":"و در آن روزها برفراز کوه برآمد تا عبادت کند وآن شب را در عبادت خدا به صبح آورد."},{"v":13,"t":"و چون روز شد، شاگردان خود را پیش طلبیده دوازده نفر از ایشان را انتخاب کرده، ایشان را نیزرسول خواند."},{"v":14,"t":"یعنی شمعون که او را پطرس نیز نام نهاد و برادرش اندریاس، یعقوب و یوحنا، فیلپس و برتولما،"},{"v":15,"t":"متی و توما، یعقوب ابن حلفی و شمعون معروف به غیور."},{"v":16,"t":"یهودا برادریعقوب و یهودای اسخریوطی که تسلیم‌کننده وی بود."},{"v":17,"t":"و با ایشان به زیر آمده، بر جای همواربایستاد. و جمعی از شاگردان وی و گروهی بسیاراز قوم، از تمام یهودیه و اورشلیم و کناره دریای صور و صیدون آمدند تا کلام او را بشنوند و ازامراض خود شفا یابند."},{"v":18,"t":"و کسانی که از ارواح پلید معذب بودند، شفا یافتند."},{"v":19,"t":"و تمام آن گروه می‌خواستند او را لمس کنند. زیرا قوتی از وی صادر شده، همه را صحت می‌بخشید."},{"v":20,"t":"پس نظر خود را به شاگردان خویش افکنده، گفت: «خوشابحال شما‌ای مساکین زیراملکوت خدا از آن شما است."},{"v":21,"t":"خوشابحال شماکه اکنون گرسنه‌اید، زیرا که سیر خواهید شد. خوشابحال شما که الحال گریانید، زیرا خواهیدخندید."},{"v":22,"t":"خوشابحال شما وقتی که مردم بخاطرپسر انسان از شما نفرت گیرند و شما را از خودجدا سازند و دشنام دهند و نام شما را مثل شریربیرون کنند."},{"v":23,"t":"در آن روز شاد باشید و وجدنمایید زیرا اینک اجر شما در آسمان عظیم می‌باشد، زیرا که به همینطور پدران ایشان با انبیاسلوک نمودند."},{"v":24,"t":"«لیکن وای بر شما‌ای دولتمندان زیرا که تسلی خود را یافته‌اید."},{"v":25,"t":"وای بر شما‌ای سیرشدگان، زیرا گرسنه خواهید شد. وای بر شماکه الان خندانید زیرا که ماتم و گریه خواهید کرد."},{"v":26,"t":"وای بر شما وقتی که جمیع مردم شما راتحسین کنند، زیرا همچنین پدران ایشان با انبیای کذبه کردند."},{"v":27,"t":"«لیکن‌ای شنوندگان شما را می‌گویم دشمنان خود را دوست دارید و با کسانی که ازشما نفرت کنند، احسان کنید."},{"v":28,"t":"و هر‌که شما رالعن کند، برای او برکت بطلبید و برای هرکه با شماکینه دارد، دعای خیر کنید."},{"v":29,"t":"و هرکه بر رخسارتو زند، دیگری را نیز به سوی او بگردان و کسی‌که ردای تو را بگیرد، قبا را نیز از او مضایقه مکن."},{"v":30,"t":"هرکه از تو سوال کند بدو بده و هر‌که مال تو راگیرد از وی باز مخواه."},{"v":31,"t":"و چنانکه می‌خواهیدمردم با شما عمل کنند، شما نیز به همانطور باایشان سلوک نمایید."},{"v":32,"t":"«زیرا اگر محبان خود را محبت نمایید، شما را چه فضیلت است؟ زیرا گناهکاران هم محبان خود را محبت می‌نمایند."},{"v":33,"t":"و اگر احسان کنید با هر‌که به شما احسان کند، چه فضیلت دارید؟ چونکه گناهکاران نیز چنین می‌کنند."},{"v":34,"t":"واگر قرض دهید به آنانی که امید بازگرفتن از ایشان دارید، شما را چه فضیلت است؟ زیرا گناهکاران نیز به گناهکاران قرض می‌دهند تا از ایشان عوض گیرند."},{"v":35,"t":"بلکه دشمنان خود را محبت نمایید واحسان کنید و بدون امید عوض، قرض دهید زیراکه اجر شما عظیم خواهد بود و پسران حضرت اعلی خواهید بود چونکه او با ناسپاسان وبدکاران مهربان است."},{"v":36,"t":"پس رحیم باشید چنانکه پدر شما نیز رحیم است."},{"v":37,"t":"«داوری مکنید تا بر شما داوری نشود وحکم مکنید تا بر شما حکم نشود و عفو کنید تاآمرزیده شوید."},{"v":38,"t":"بدهید تا به شما داده شود. زیرا پیمانه نیکوی افشرده و جنبانیده و لبریز شده را در دامن شما خواهند گذارد. زیرا که به همان پیمانه‌ای که می‌پیمایید برای شما پیموده خواهدشد.»"},{"v":39,"t":"پس برای ایشان مثلی زد که «آیا می‌تواند کور، کور را راهنمایی کند؟ آیا هر دو در حفره‌ای نمی افتند؟"},{"v":40,"t":"شاگرد از معلم خویش بهتر نیست لیکن هر‌که کامل شده باشد، مثل استاد خود بود."},{"v":41,"t":"و چرا خسی را که در چشم برادر تو است می‌بینی و چوبی را که در چشم خود داری نمی یابی؟"},{"v":42,"t":"و چگونه بتوانی برادر خود را گویی‌ای برادر اجازت ده تا خس را از چشم تو برآورم و چوبی را که در چشم خود داری نمی بینی. ای ریاکار اول چوب را از چشم خود بیرون کن، آنگاه نیکو خواهی دید تا خس را از چشم برادر خودبرآوری."},{"v":43,"t":"«زیرا هیچ درخت نیکو میوه بد بارنمی آورد و نه درخت بد، میوه نیکو آورد."},{"v":44,"t":"زیراکه هر درخت از میوه‌اش شناخته می‌شود از خارانجیر را نمی یابند و از بوته، انگور را نمی چینند."},{"v":45,"t":"آدم نیکو از خزینه خوب دل خود چیز نیکوبرمی آورد و شخص شریر از خزینه بد دل خویش چیز بد بیرون می‌آورد. زیرا که از زیادتی دل زبان سخن می‌گوید."},{"v":46,"t":"«و چون است که مرا خداوندا خداوندامی گویید و آنچه می‌گویم بعمل نمی آورید."},{"v":47,"t":"هر‌که نزد من آید و سخنان مرا شنود و آنها را به‌جا آورد، شما را نشان می‌دهم که به چه کس مشابهت دارد."},{"v":48,"t":"مثل شخصی است که خانه‌ای می‌ساخت و زمین را کنده گود نمود و بنیادش رابر سنگ نهاد. پس چون سیلاب آمده، سیل بر آن خانه زور آورد، نتوانست آن را جنبش دهد زیراکه بر سنگ بنا شده بود."},{"v":49,"t":"لیکن هر‌که شنید وعمل نیاورد مانند شخصی است که خانه‌ای برروی زمین بی‌بنیاد بنا کرد که چون سیل بر آن صدمه زد، فور افتاد و خرابی آن خانه عظیم بود.»"}],"en":[{"v":1,"t":"Now on the second Sabbath after the first, he was going through the grain fields. His disciples plucked the heads of grain and ate, rubbing them in their hands."},{"v":2,"t":"But some of the Pharisees said to them, “Why do you do that which is not lawful to do on the Sabbath day?”"},{"v":3,"t":"Jesus, answering them, said, “Haven’t you read what David did when he was hungry, he and those who were with him,"},{"v":4,"t":"how he entered into God’s house, and took and ate the show bread, and gave also to those who were with him, which is not lawful to eat except for the priests alone?”"},{"v":5,"t":"He said to them, “The Son of Man is lord of the Sabbath.”"},{"v":6,"t":"It also happened on another Sabbath that he entered into the synagogue and taught. There was a man there, and his right hand was withered."},{"v":7,"t":"The scribes and the Pharisees watched him, to see whether he would heal on the Sabbath, that they might find an accusation against him."},{"v":8,"t":"But he knew their thoughts; and he said to the man who had the withered hand, “Rise up and stand in the middle.” He arose and stood."},{"v":9,"t":"Then Jesus said to them, “I will ask you something: Is it lawful on the Sabbath to do good, or to do harm? To save a life, or to kill?”"},{"v":10,"t":"He looked around at them all, and said to the man, “Stretch out your hand.” He did, and his hand was restored as sound as the other."},{"v":11,"t":"But they were filled with rage, and talked with one another about what they might do to Jesus."},{"v":12,"t":"In these days, he went out to the mountain to pray, and he continued all night in prayer to God."},{"v":13,"t":"When it was day, he called his disciples, and from them he chose twelve, whom he also named apostles:"},{"v":14,"t":"Simon, whom he also named Peter; Andrew, his brother; James; John; Philip; Bartholomew;"},{"v":15,"t":"Matthew; Thomas; James the son of Alphaeus; Simon who was called the Zealot;"},{"v":16,"t":"Judas the son of James; and Judas Iscariot, who also became a traitor."},{"v":17,"t":"He came down with them and stood on a level place, with a crowd of his disciples and a great number of the people from all Judea and Jerusalem and the sea coast of Tyre and Sidon, who came to hear him and to be healed of their diseases,"},{"v":18,"t":"as well as those who were troubled by unclean spirits; and they were being healed."},{"v":19,"t":"All the multitude sought to touch him, for power came out of him and healed them all."},{"v":20,"t":"He lifted up his eyes to his disciples, and said: “Blessed are you who are poor, for God’s Kingdom is yours."},{"v":21,"t":"Blessed are you who hunger now, for you will be filled. Blessed are you who weep now, for you will laugh."},{"v":22,"t":"Blessed are you when men hate you, and when they exclude and mock you, and throw out your name as evil, for the Son of Man’s sake."},{"v":23,"t":"Rejoice in that day and leap for joy, for behold, your reward is great in heaven, for their fathers did the same thing to the prophets."},{"v":24,"t":"“But woe to you who are rich! For you have received your consolation."},{"v":25,"t":"Woe to you, you who are full now, for you will be hungry. Woe to you who laugh now, for you will mourn and weep."},{"v":26,"t":"Woe, when men speak well of you, for their fathers did the same thing to the false prophets."},{"v":27,"t":"“But I tell you who hear: love your enemies, do good to those who hate you,"},{"v":28,"t":"bless those who curse you, and pray for those who mistreat you."},{"v":29,"t":"To him who strikes you on the cheek, offer also the other; and from him who takes away your cloak, don’t withhold your coat also."},{"v":30,"t":"Give to everyone who asks you, and don’t ask him who takes away your goods to give them back again."},{"v":31,"t":"“As you would like people to do to you, do exactly so to them."},{"v":32,"t":"“If you love those who love you, what credit is that to you? For even sinners love those who love them."},{"v":33,"t":"If you do good to those who do good to you, what credit is that to you? For even sinners do the same."},{"v":34,"t":"If you lend to those from whom you hope to receive, what credit is that to you? Even sinners lend to sinners, to receive back as much."},{"v":35,"t":"But love your enemies, and do good, and lend, expecting nothing back; and your reward will be great, and you will be children of the Most High; for he is kind toward the unthankful and evil."},{"v":36,"t":"“Therefore be merciful, even as your Father is also merciful."},{"v":37,"t":"Don’t judge, and you won’t be judged. Don’t condemn, and you won’t be condemned. Set free, and you will be set free."},{"v":38,"t":"“Give, and it will be given to you: good measure, pressed down, shaken together, and running over, will be given to you. For with the same measure you measure it will be measured back to you.”"},{"v":39,"t":"He spoke a parable to them. “Can the blind guide the blind? Won’t they both fall into a pit?"},{"v":40,"t":"A disciple is not above his teacher, but everyone when he is fully trained will be like his teacher."},{"v":41,"t":"Why do you see the speck of chaff that is in your brother’s eye, but don’t consider the beam that is in your own eye?"},{"v":42,"t":"Or how can you tell your brother, ‘Brother, let me remove the speck of chaff that is in your eye,’ when you yourself don’t see the beam that is in your own eye? You hypocrite! First remove the beam from your own eye, and then you can see clearly to remove the speck of chaff that is in your brother’s eye."},{"v":43,"t":"“For there is no good tree that produces rotten fruit, nor again a rotten tree that produces good fruit."},{"v":44,"t":"For each tree is known by its own fruit. For people don’t gather figs from thorns, nor do they gather grapes from a bramble bush."},{"v":45,"t":"The good man out of the good treasure of his heart brings out that which is good, and the evil man out of the evil treasure of his heart brings out that which is evil, for out of the abundance of the heart, his mouth speaks."},{"v":46,"t":"“Why do you call me, ‘Lord, Lord,’ and don’t do the things which I say?"},{"v":47,"t":"Everyone who comes to me, and hears my words and does them, I will show you who he is like."},{"v":48,"t":"He is like a man building a house, who dug and went deep and laid a foundation on the rock. When a flood arose, the stream broke against that house, and could not shake it, because it was founded on the rock."},{"v":49,"t":"But he who hears and doesn’t do, is like a man who built a house on the earth without a foundation, against which the stream broke, and immediately it fell; and the ruin of that house was great.”"}],"hr":[{"v":1,"t":"Jedne je subote prolazio kroz usjeve. Učenici su njegovi trgali klasje, trli ga rukama i jeli."},{"v":2,"t":"A neki farizeji rekoše: “Zašto činite što subotom nije dopušteno?”"},{"v":3,"t":"Odgovori im Isus: “Zar niste čitali što učini David kad ogladnje on i njegovi pratioci?"},{"v":4,"t":"Kako uđe u Dom Božji, uze, pojede i svojim pratiocima dade prinesene kruhove kojih ne smije jesti nitko, nego samo svećenici?”"},{"v":5,"t":"I govoraše im: “Sin Čovječji gospodar je subote!”"},{"v":6,"t":"Druge subote uđe u sinagogu i stane naučavati. Bio je ondje čovjek kome desnica bijaše usahla."},{"v":7,"t":"Pismoznanci i farizeji vrebahu na nj da li subotom liječi kako bi našli u čemu da ga optuže."},{"v":8,"t":"A on je znao njihove namjere pa reče čovjeku s usahlom rukom: “Ustani i stani na sredinu!” On usta i stade."},{"v":9,"t":"A Isus im reče: “Pitam ja vas: je li subotom dopušteno činiti dobro ili činiti zlo? Život spasiti ili upropastiti?”"},{"v":10,"t":"Sve ih ošinu pogledom pa reče čovjeku: “Ispruži ruku!” On učini tako - i ruka mu zdrava."},{"v":11,"t":"A oni se, izbezumljeni, počnu dogovarati što da poduzmu protiv Isusa."},{"v":12,"t":"Onih dana iziđe na goru da se pomoli. I provede noć moleći se Bogu."},{"v":13,"t":"Kad se razdanilo, dozva k sebi učenike te između njih izabra dvanaestoricu, koje prozva apostolima:"},{"v":14,"t":"Šimuna, koga prozva Petrom, i Andriju, brata njegova, i Jakova, i Ivana, i Filipa, i Bartolomeja,"},{"v":15,"t":"i Mateja, i Tomu, i Jakova Alfejeva, i Šimuna zvanoga Revnitelj,"},{"v":16,"t":"i Judu Jakovljeva, i Judu Iškariotskoga, koji posta izdajica."},{"v":17,"t":"Isus siđe s njima i zaustavi se na ravnu. I silno mnoštvo njegovih učenika i silno mnoštvo naroda iz cijele Judeje i Jeruzalema, iz primorja tirskog i sidonskog"},{"v":18,"t":"nagrnuše da ga slušaju i da ozdrave od svojih bolesti. I ozdravljali su oni koje su mučili nečisti dusi."},{"v":19,"t":"Sve je to mnoštvo tražilo da ga se dotakne jer je snaga izlazila iz njega i sve ozdravljala."},{"v":20,"t":"On podigne oči prema učenicima i govoraše: “Blago vama, siromasi: vaše je kraljevstvo Božje!"},{"v":21,"t":"Blago vama koji sada gladujete: vi ćete se nasititi! Blago vama koji sada plačete: vi ćete se smijati!"},{"v":22,"t":"Blago vama kad vas zamrze ljudi i kad vas izopće i pogrde te izbace ime vaše kao zločinačko zbog Sina Čovječjega!"},{"v":23,"t":"Radujte se u dan onaj i poskakujte: evo, plaća vaša velika je na nebu. Ta jednako su činili prorocima oci njihovi!”"},{"v":24,"t":"“Ali jao vama, bogataši: imate svoju utjehu!"},{"v":25,"t":"Jao vama koji ste sada siti: gladovat ćete! Jao vama koji se sada smijete: jadikovat ćete i plakati!"},{"v":26,"t":"Jao vama kad vas svi budu hvalili! Ta tako su činili lažnim prorocima oci njihovi.”"},{"v":27,"t":"“Nego, velim vama koji slušate: Ljubite svoje neprijatelje, dobro činite svojim mrziteljima,"},{"v":28,"t":"blagoslivljajte one koji vas proklinju, molite za one koji vas zlostavljaju.”"},{"v":29,"t":"“Onomu tko te udari po jednom obrazu pruži i drugi, i onomu tko ti otima gornju haljinu ne krati ni donje."},{"v":30,"t":"Svakomu tko od tebe ište daji, a od onoga tko tvoje otima ne potražuj.”"},{"v":31,"t":"“I kako želite da ljudi vama čine, tako činite i vi njima.”"},{"v":32,"t":"“Ako ljubite one koji vas ljube, kakvo li vam uzdarje? Ta i grešnici ljube ljubitelje svoje."},{"v":33,"t":"Jednako tako, ako dobro činite svojim dobročiniteljima, kakvo li vam uzdarje? I grešnici to isto čine."},{"v":34,"t":"Ako pozajmljujete samo onima od kojih se nadate dobiti, kakvo li vam uzdarje? I grešnici grešnicima pozajmljuju da im se jednako vrati.”"},{"v":35,"t":"“Nego, ljubite neprijatelje svoje. Činite dobro i pozajmljujte ne nadajuć se odatle ničemu. I bit će vam plaća velika, i bit ćete sinovi Svevišnjega jer je on dobrostiv i prema nezahvalnicima i prema opakima.”"},{"v":36,"t":"“Budite milosrdni kao što je Otac vaš milosrdan.”"},{"v":37,"t":"“Ne sudite i nećete biti suđeni. Ne osuđujte i nećete biti osuđeni. Praštajte i oprostit će vam se."},{"v":38,"t":"Dajite i dat će vam se: mjera dobra, nabijena, natresena, preobilna dat će se u krilo vaše jer mjerom kojom mjerite vama će se zauzvrat mjeriti.”"},{"v":39,"t":"A kaza im i prispodobu: “Može li slijepac slijepca voditi? Neće li obojica u jamu upasti?"},{"v":40,"t":"Nije učenik nad učiteljem. Pa i tko je posve doučen, bit će samo kao njegov učitelj.”"},{"v":41,"t":"“Što gledaš trun u oku brata svojega, a brvna u oku svome ne opažaš?"},{"v":42,"t":"Kako možeš kazati bratu svomu: 'Brate, de da izvadim trun koji ti je u oku', a sam u svom oku brvna ne vidiš? Licemjere! Izvadi najprije brvno iz oka svoga pa ćeš onda dobro vidjeti izvaditi trun što je u oku bratovu.”"},{"v":43,"t":"“Nema dobra stabla koje bi rađalo nevaljalim plodom niti stabla nevaljala koje bi rađalo dobrim plodom."},{"v":44,"t":"Ta svako se stablo po svom plodu poznaje. S trnja se ne beru smokve niti se s gloga grožđe trga.”"},{"v":45,"t":"“Dobar čovjek iz dobra blaga srca svojega iznosi dobro, a zao iz zla iznosi zlo. Ta iz obilja srca usta mu govore.”"},{"v":46,"t":"“Što me zovete 'Gospodine, Gospodine!', a ne činite što zapovijedam?"},{"v":47,"t":"Tko god dolazi k meni te sluša moje riječi i vrši ih, pokazat ću vam kome je sličan:"},{"v":48,"t":"sličan je čovjeku koji gradi kuću pa iskopa u dubinu i postavi temelj na kamen. A kad bude poplava, nahrupi bujica na tu kuću, ali je ne može uzdrmati jer je dobro sagrađena."},{"v":49,"t":"A koji čuje i ne izvrši, sličan je čovjeku koji sagradi kuću na tlu bez temelja; nahrupi na nju bujica i umah se sruši te bude od te kuće razvalina velika.”"}]},"7":{"fa":[{"v":1,"t":"و چون همه سخنان خود را به سمع خلق به اتمام رسانید، وارد کفرناحوم شد."},{"v":2,"t":"ویوزباشی را غلامی که عزیز او بود مریض ومشرف بر موت بود."},{"v":3,"t":"چون خبر عیسی را شنید، مشایخ یهود را نزد وی فرستاده از او خواهش کرد که آمده غلام او را شفا بخشد."},{"v":4,"t":"ایشان نزدعیسی آمده به الحاح نزد او التماس کرده گفتند: «مستحق است که این احسان را برایش به‌جاآوری."},{"v":5,"t":"زیرا قوم ما را دوست می‌دارد و خودبرای ما کنیسه را ساخت.»"},{"v":6,"t":"پس عیسی با ایشان روانه شد و چون نزدیک به خانه رسید، یوزباشی چند نفر از دوستان خودرا نزد او فرستاده بدو گفت: «خداوندا زحمت مکش زیرا لایق آن نیستم که زیر سقف من درآیی."},{"v":7,"t":"و از این سبب خود را لایق آن ندانستم که نزد تو آیم، بلکه سخنی بگو تا بنده من صحیح شود."},{"v":8,"t":"زیرا که من نیز شخصی هستم زیر حکم ولشکریان زیر دست خود دارم. چون به یکی گویم برو، می‌رود و به دیگری بیا، می‌آید و به غلام خود این را بکن، می‌کند.»"},{"v":9,"t":"چون عیسی این راشنید، تعجب نموده به سوی آن جماعتی که از عقب او می‌آمدند روی گردانیده، گفت: «به شمامی گویم چنین ایمانی، در اسرائیل هم نیافته‌ام.»"},{"v":10,"t":"پس فرستادگان به خانه برگشته، آن غلام بیماررا صحیح یافتند."},{"v":11,"t":"و دو روز بعد به شهری مسمی به نائین می‌رفت و بسیاری از شاگردان او و گروهی عظیم، همراهش می‌رفتند."},{"v":12,"t":"چون نزدیک به دروازه شهر رسید، ناگاه میتی را که پسر یگانه بیوه‌زنی بود می‌بردند و انبوهی کثیر از اهل شهر، با وی می‌آمدند."},{"v":13,"t":"چون خداوند او را دید، دلش بر اوبسوخت و به وی گفت: «گریان مباش.»"},{"v":14,"t":"و نزدیک آمده تابوت را لمس نمود وحاملان آن بایستادند. پس گفت: «ای جوان تو رامی گویم برخیز.»"},{"v":15,"t":"در ساعت آن مرده راست بنشست و سخن‌گفتن آغاز کرد و او را به مادرش سپرد."},{"v":16,"t":"پس خوف همه را فراگرفت و خدا راتمجیدکنان می‌گفتند که «نبی‌ای بزرگ در میان مامبعوث شده و خدا از قوم خود تفقد نموده است.»"},{"v":17,"t":"پس این خبر درباره او در تمام یهودیه و جمیع آن مرز و بوم منتشر شد."},{"v":18,"t":"و شاگردان یحیی او را از جمیع این وقایع مطلع ساختند."},{"v":19,"t":"پس یحیی دو نفر از شاگردان خود را طلبیده، نزد عیسی فرستاده، عرض نمودکه «آیا تو آن آینده هستی یا منتظر دیگری باشیم؟»"},{"v":20,"t":"آن دو نفر نزد وی آمده، گفتند: «یحیی تعمید‌دهنده ما را نزد تو فرستاده، می‌گوید آیا تو آن آینده هستی یا منتظر دیگری باشیم.»"},{"v":21,"t":"در همان ساعت، بسیاری را از مرضهاو بلایا و ارواح پلید شفا داد و کوران بسیاری رابینایی بخشید."},{"v":22,"t":"عیسی در جواب ایشان گفت: «بروید و یحیی را از آنچه دیده و شنیده‌اید خبردهید که کوران، بینا و لنگان خرامان و ابرصان طاهر و کران، شنوا و مردگان، زنده می‌گردند و به فقرا بشارت داده می‌شود."},{"v":23,"t":"و خوشابحال کسی‌که در من لغزش نخورد.»"},{"v":24,"t":"و چون فرستادگان یحیی رفته بودند، درباره یحیی بدان جماعت آغاز سخن نهاد که «برای دیدن چه چیز به صحرا بیرون رفته بودید، آیا نی را که از باد در جنبش است؟"},{"v":25,"t":"بلکه بجهت دیدن چه بیرون رفتید، آیا کسی را که به لباس نرم ملبس باشد؟ اینک آنانی که لباس فاخر می‌پوشندو عیاشی می‌کنند، در قصرهای سلاطین هستند."},{"v":26,"t":"پس برای دیدن چه رفته بودید، آیا نبی‌ای را؟ بلی به شما می‌گویم کسی را که از نبی هم بزرگتراست."},{"v":27,"t":"زیرا این است آنکه درباره وی مکتوب است، اینک من رسول خود را پیش روی تومی فرستم تا راه تو را پیش تو مهیا سازد."},{"v":28,"t":"زیراکه شما را می‌گویم از اولاد زنان نبی‌ای بزرگتر ازیحیی تعمید‌دهنده نیست، لیکن آنکه در ملکوت خدا کوچکتر است از وی بزرگتر است.»"},{"v":29,"t":"وتمام قوم و باجگیران چون شنیدند، خدا راتمجید کردند زیرا که تعمید از یحیی یافته بودند."},{"v":30,"t":"لیکن فریسیان و فقها اراده خدا را از خود ردنمودند زیرا که از وی تعمید نیافته بودند."},{"v":31,"t":"آنگاه خداوند گفت: «مردمان این طبقه را به چه تشبیه کنم و مانند چه می‌باشند؟"},{"v":32,"t":"اطفالی را می مانند که در بازارها نشسته، یکدیگر را صدازده می‌گویند، برای شما نواختیم رقص نکردید ونوحه گری کردیم گریه ننمودید."},{"v":33,"t":"زیرا که یحیی تعمید‌دهنده آمد که نه نان می‌خورد و نه شراب می‌آشامید، می‌گویید دیو دارد."},{"v":34,"t":"پسر انسان آمد که می‌خورد و می‌آشامد، می‌گویید اینک مردی است پرخور و باده پرست و دوست باجگیران و گناهکاران."},{"v":35,"t":"اما حکمت از جمیع فرزندان خود مصدق می‌شود."},{"v":36,"t":"و یکی از فریسیان از او وعده خواست که بااو غذا خورد پس به خانه فریسی درآمده بنشست."},{"v":37,"t":"که ناگاه زنی که در آن شهر گناهکاربود، چون شنید که در خانه فریسی به غذا نشسته است شیشه‌ای از عطر آورده،"},{"v":38,"t":"در پشت سر اونزد پایهایش گریان بایستاد و شروع کرد به شستن پایهای او به اشک خود و خشکانیدن آنها به موی سر خود و پایهای وی را بوسیده آنها را به عطرتدهین کرد."},{"v":39,"t":"چون فریسی‌ای که از او وعده خواسته بوداین را بدید، با خود می‌گفت که «این شخص اگرنبی بودی هرآینه دانستی که این کدام و چگونه زن است که او را لمس می‌کند، زیرا گناهکاری است.»"},{"v":40,"t":"عیسی جواب داده به وی گفت: «ای شمعون چیزی دارم که به تو گویم.» گفت: «ای استاد بگو.»"},{"v":41,"t":"گفت: «طلبکاری را دو بدهکار بودکه از یکی پانصد و از دیگری پنجاه دینار طلب داشتی."},{"v":42,"t":"چون چیزی نداشتند که ادا کنند، هر دو را بخشید. بگو کدام‌یک از آن دو او را زیادترمحبت خواهد نمود.»"},{"v":43,"t":"شمعون در جواب گفت: «گمان می‌کنم آنکه او را زیادتر بخشید.» به وی گفت: «نیکو گفتی.»"},{"v":44,"t":"پس به سوی آن زن اشاره نموده به شمعون گفت: «این زن را نمی بینی، به خانه تو آمدم آب بجهت پایهای من نیاوردی، ولی این زن پایهای مرا به اشکها شست و به مویهای سر خود آنها راخشک کرد."},{"v":45,"t":"مرا نبوسیدی، لیکن این زن ازوقتی که داخل شدم از بوسیدن پایهای من بازنایستاد."},{"v":46,"t":"سر مرا به روغن مسح نکردی، لیکن اوپایهای مرا به عطر تدهین کرد."},{"v":47,"t":"از این جهت به تو می‌گویم، گناهان او که بسیار است آمرزیده شد، زیرا که محبت بسیار نموده است. لیکن آنکه آمرزش کمتر یافت، محبت کمتر می‌نماید.»"},{"v":48,"t":"پس به آن زن گفت: «گناهان تو آمرزیده شد.»"},{"v":49,"t":"و اهل مجلس در خاطر خود تفکر آغاز کردندکه این کیست که گناهان را هم می‌آمرزد."},{"v":50,"t":"پس به آن زن گفت: «ایمانت تو را نجات داده است به سلامتی روانه شو.»"}],"en":[{"v":1,"t":"After he had finished speaking in the hearing of the people, he entered into Capernaum."},{"v":2,"t":"A certain centurion’s servant, who was dear to him, was sick and at the point of death."},{"v":3,"t":"When he heard about Jesus, he sent to him elders of the Jews, asking him to come and save his servant."},{"v":4,"t":"When they came to Jesus, they begged him earnestly, saying, “He is worthy for you to do this for him,"},{"v":5,"t":"for he loves our nation, and he built our synagogue for us.”"},{"v":6,"t":"Jesus went with them. When he was now not far from the house, the centurion sent friends to him, saying to him, “Lord, don’t trouble yourself, for I am not worthy for you to come under my roof."},{"v":7,"t":"Therefore I didn’t even think myself worthy to come to you; but say the word, and my servant will be healed."},{"v":8,"t":"For I also am a man placed under authority, having under myself soldiers. I tell this one, ‘Go!’ and he goes; and to another, ‘Come!’ and he comes; and to my servant, ‘Do this,’ and he does it.”"},{"v":9,"t":"When Jesus heard these things, he marveled at him, and turned and said to the multitude who followed him, “I tell you, I have not found such great faith, no, not in Israel.”"},{"v":10,"t":"Those who were sent, returning to the house, found that the servant who had been sick was well."},{"v":11,"t":"Soon afterwards, he went to a city called Nain. Many of his disciples, along with a great multitude, went with him."},{"v":12,"t":"Now when he came near to the gate of the city, behold, one who was dead was carried out, the only born son of his mother, and she was a widow. Many people of the city were with her."},{"v":13,"t":"When the Lord saw her, he had compassion on her and said to her, “Don’t cry.”"},{"v":14,"t":"He came near and touched the coffin, and the bearers stood still. He said, “Young man, I tell you, arise!”"},{"v":15,"t":"He who was dead sat up and began to speak. Then he gave him to his mother."},{"v":16,"t":"Fear took hold of all, and they glorified God, saying, “A great prophet has arisen among us!” and, “God has visited his people!”"},{"v":17,"t":"This report went out concerning him in the whole of Judea and in all the surrounding region."},{"v":18,"t":"The disciples of John told him about all these things."},{"v":19,"t":"John, calling to himself two of his disciples, sent them to Jesus, saying, “Are you the one who is coming, or should we look for another?”"},{"v":20,"t":"When the men had come to him, they said, “John the Baptizer has sent us to you, saying, ‘Are you he who comes, or should we look for another?’”"},{"v":21,"t":"In that hour he cured many of diseases and plagues and evil spirits; and to many who were blind he gave sight."},{"v":22,"t":"Jesus answered them, “Go and tell John the things which you have seen and heard: that the blind receive their sight, the lame walk, the lepers are cleansed, the deaf hear, the dead are raised up, and the poor have good news preached to them."},{"v":23,"t":"Blessed is he who finds no occasion for stumbling in me.”"},{"v":24,"t":"When John’s messengers had departed, he began to tell the multitudes about John, “What did you go out into the wilderness to see? A reed shaken by the wind?"},{"v":25,"t":"But what did you go out to see? A man clothed in soft clothing? Behold, those who are gorgeously dressed and live delicately are in kings’ courts."},{"v":26,"t":"But what did you go out to see? A prophet? Yes, I tell you, and much more than a prophet."},{"v":27,"t":"This is he of whom it is written, ‘Behold, I send my messenger before your face, who will prepare your way before you.’"},{"v":28,"t":"“For I tell you, among those who are born of women there is not a greater prophet than John the Baptizer; yet he who is least in God’s Kingdom is greater than he.”"},{"v":29,"t":"When all the people and the tax collectors heard this, they declared God to be just, having been baptized with John’s baptism."},{"v":30,"t":"But the Pharisees and the lawyers rejected the counsel of God, not being baptized by him themselves."},{"v":31,"t":"“To what then should I compare the people of this generation? What are they like?"},{"v":32,"t":"They are like children who sit in the marketplace and call to one another, saying, ‘We piped to you, and you didn’t dance. We mourned, and you didn’t weep.’"},{"v":33,"t":"For John the Baptizer came neither eating bread nor drinking wine, and you say, ‘He has a demon.’"},{"v":34,"t":"The Son of Man has come eating and drinking, and you say, ‘Behold, a glutton and a drunkard, a friend of tax collectors and sinners!’"},{"v":35,"t":"Wisdom is justified by all her children.”"},{"v":36,"t":"One of the Pharisees invited him to eat with him. He entered into the Pharisee’s house and sat at the table."},{"v":37,"t":"Behold, a woman in the city who was a sinner, when she knew that he was reclining in the Pharisee’s house, brought an alabaster jar of ointment."},{"v":38,"t":"Standing behind at his feet weeping, she began to wet his feet with her tears, and she wiped them with the hair of her head, kissed his feet, and anointed them with the ointment."},{"v":39,"t":"Now when the Pharisee who had invited him saw it, he said to himself, “This man, if he were a prophet, would have perceived who and what kind of woman this is who touches him, that she is a sinner.”"},{"v":40,"t":"Jesus answered him, “Simon, I have something to tell you.” He said, “Teacher, say on.”"},{"v":41,"t":"“A certain lender had two debtors. The one owed five hundred denarii, and the other fifty."},{"v":42,"t":"When they couldn’t pay, he forgave them both. Which of them therefore will love him most?”"},{"v":43,"t":"Simon answered, “He, I suppose, to whom he forgave the most.” He said to him, “You have judged correctly.”"},{"v":44,"t":"Turning to the woman, he said to Simon, “Do you see this woman? I entered into your house, and you gave me no water for my feet, but she has wet my feet with her tears, and wiped them with the hair of her head."},{"v":45,"t":"You gave me no kiss, but she, since the time I came in, has not ceased to kiss my feet."},{"v":46,"t":"You didn’t anoint my head with oil, but she has anointed my feet with ointment."},{"v":47,"t":"Therefore I tell you, her sins, which are many, are forgiven, for she loved much. But one to whom little is forgiven, loves little.”"},{"v":48,"t":"He said to her, “Your sins are forgiven.”"},{"v":49,"t":"Those who sat at the table with him began to say to themselves, “Who is this who even forgives sins?”"},{"v":50,"t":"He said to the woman, “Your faith has saved you. Go in peace.”"}],"hr":[{"v":1,"t":"Pošto dovrši sve te svoje besjede narodu, uđe u Kafarnaum."},{"v":2,"t":"Nekomu satniku bijaše bolestan sluga, samo što ne izdahnu, a bijaše mu veoma drag."},{"v":3,"t":"Kad je satnik čuo za Isusa, posla k njemu starješine židovske moleći ga da dođe i ozdravi mu slugu."},{"v":4,"t":"Kad oni dođoše Isusu, usrdno ga moljahu: “Dostojan je da mu to učiniš"},{"v":5,"t":"jer voli naš narod, i sinagogu nam je sagradio.”"},{"v":6,"t":"Isus se uputi s njima. I kad bijaše već kući nadomak, posla satnik prijatelje s porukom: “Gospodine, ne muči se. Nisam dostojan da uđeš pod krov moj."},{"v":7,"t":"Zato se i ne smatrah dostojnim doći k tebi. Nego - reci riječ da ozdravi sluga moj."},{"v":8,"t":"Ta i ja, premda sam vlasti podređen, imam pod sobom vojnike pa reknem jednomu: 'Idi' - i ode, drugomu: 'Dođi' - i dođe, a sluzi svomu: 'Učini to' - i učini.”"},{"v":9,"t":"Čuvši to, zadivi mu se Isus pa se okrenu mnoštvu koje je išlo za njim i reče: “Kažem vam, ni u Izraelu na nađoh tolike vjere.”"},{"v":10,"t":"Kad se oni koji su bili poslani vratiše kući, nađoše slugu zdrava."},{"v":11,"t":"Nakon toga uputi se Isus u grad zvani Nain. Pratili ga njegovi učenici i silan svijet."},{"v":12,"t":"Kad se približi gradskim vratima, gle, upravo su iznosili mrtvaca, sina jedinca u majke, majke udovice. Pratilo ju mnogo naroda iz grada."},{"v":13,"t":"Kad je Gospodin ugleda, sažali mu se nad njom i reče joj: “Ne plači!”"},{"v":14,"t":"Pristupi zatim, dotače se nosila; nosioci stadoše, a on reče: “Mladiću, kažem ti, ustani!”"},{"v":15,"t":"I mrtvac se podiže i progovori, a on ga dade njegovoj majci."},{"v":16,"t":"Sve obuze strah te slavljahu Boga govoreći: “Prorok velik usta među nama! Pohodi Bog narod svoj!”"},{"v":17,"t":"I proširi se taj glas o njemu po svoj Judeji i po svoj okolici."},{"v":18,"t":"Sve to dojaviše Ivanu njegovi učenici. On dozva dvojicu svojih učenika"},{"v":19,"t":"i posla ih Gospodinu da ga pitaju: “Jesi li ti Onaj koji ima doći ili drugoga da čekamo?”"},{"v":20,"t":"Došavši k njemu, rekoše ti ljudi: “Ivan Krstitelj posla nas k tebi da pitamo: 'Jesi li ti Onaj koji ima doći ili drugoga da čekamo?'”"},{"v":21,"t":"Upravo u taj čas Isus je ozdravio mnoge od bolesti, muka i zlih duhova i mnoge je slijepe podario vidom."},{"v":22,"t":"Tada im odgovori: “Pođite i javite Ivanu što ste vidjeli i čuli: Slijepi progledaju, hromi hode, gubavi se čiste, gluhi čuju, mrtvi ustaju, siromasima se navješćuje evanđelje."},{"v":23,"t":"I blago onom tko se ne sablazni o mene.”"},{"v":24,"t":"Kad Ivanovi glasnici odoše, poče Isus govoriti mnoštvu o Ivanu: “Što ste izašli u pustinju gledati? Trsku koju vjetar ljulja?"},{"v":25,"t":"Ili što ste izašli vidjeti: Čovjeka u mekušaste haljine odjevena? Eno, oni u sjajnoj odjeći i raskošju po kraljevskim su dvorima."},{"v":26,"t":"Ili što ste izašli vidjeti? Proroka? Uistinu, kažem vam, i više nego proroka!"},{"v":27,"t":"On je onaj o kome je pisano: Evo, šaljem glasnika svoga pred licem tvojim da pripravi put pred tobom."},{"v":28,"t":"Kažem vam: među rođenima od žene nitko nije veći od Ivana. A ipak, i najmanji u kraljevstvu Božjem veći je od njega.”"},{"v":29,"t":"Sav narod koji ga je slušao, pa i carinici, uvidješe pravednost Božju: pokrstiše se Ivanovim krstom."},{"v":30,"t":"Naprotiv, farizeji i zakonoznanci ometoše što je Bog s njima naumio jer ne htjedoše da ih Ivan krsti."},{"v":31,"t":"“S kime dakle da prispodobim ljude ovog naraštaja? Komu su nalik?"},{"v":32,"t":"Nalik su djeci što sjede na trgu pa jedni drugima po poslovici dovikuju: 'Zasvirasmo vam i ne zaigraste! Zakukasmo i ne zaplakaste!'"},{"v":33,"t":"Doista, došao je Ivan Krstitelj. Nije kruha jeo ni vina pio, a velite: 'Ðavla ima!'"},{"v":34,"t":"Došao je Sin Čovječji koji jede i pije, a govorite: 'Evo izjelice i vinopije, prijatelja carinika i grešnika!'"},{"v":35,"t":"Ali opravda se Mudrost pred svom djecom svojom.”"},{"v":36,"t":"Neki farizej pozva Isusa da bi blagovao s njime. On uđe u kuću farizejevu i priđe stolu."},{"v":37,"t":"Kad eto neke žene koja bijaše grešnica u gradu. Dozna da je Isus za stolom u farizejevoj kući pa ponese alabastrenu posudicu pomasti"},{"v":38,"t":"i stade odostrag kod njegovih nogu. Sva zaplakana poče mu suzama kvasiti noge: kosom ih glave svoje otirala, cjelivala i mazala pomašću."},{"v":39,"t":"Kad to vidje farizej koji ga pozva, pomisli: “Kad bi ovaj bio Prorok, znao bi tko i kakva je to žena koja ga se dotiče: da je grešnica.”"},{"v":40,"t":"A Isus, da mu odgovori, reče: “Šimune, imam ti nešto reći.” A on će: “Učitelju, reci!” A on:"},{"v":41,"t":"“Neki vjerovnik imao dva dužnika. Jedan mu dugovaše pet stotina denara, drugi pedeset."},{"v":42,"t":"Budući da nisu imali odakle vratiti, otpusti obojici. Koji će ga dakle od njih više ljubiti?”"},{"v":43,"t":"Šimun odgovori: “Predmnijevam, onaj kojemu je više otpustio.” Reče mu Isus: “Pravo si prosudio.”"},{"v":44,"t":"I okrenut ženi reče Šimunu: “Vidiš li ovu ženu? Uđoh ti u kuću, nisi mi vodom noge polio, a ona mi suzama noge oblila i kosom ih svojom otrla."},{"v":45,"t":"Poljupca mi nisi dao, a ona, otkako uđe, ne presta mi noge cjelivati."},{"v":46,"t":"Uljem mi glave nisi pomazao, a ona mi pomašću noge pomaza."},{"v":47,"t":"Stoga, kažem ti, oprošteni su joj grijesi mnogi jer ljubljaše mnogo. Komu se malo oprašta, malo ljubi.”"},{"v":48,"t":"A ženi reče: “Oprošteni su ti grijesi.”"},{"v":49,"t":"Sustolnici počeli nato među sobom govoriti: “Tko je ovaj da i grijehe oprašta?”"},{"v":50,"t":"A on reče ženi: “Vjera te tvoja spasila! Idi u miru!”"}]},"8":{"fa":[{"v":1,"t":"و بعد از آن واقع شد که او در هر شهری ودهی گشته، موعظه می‌نمود و به ملکوت خدا بشارت می‌داد و آن دوازده با وی می‌بودند."},{"v":2,"t":"و زنان چند که از ارواح پلید و مرضها شفا یافته بودند، یعنی مریم معروف به مجدلیه که از اوهفت دیو بیرون رفته بودند،"},{"v":3,"t":"و یونا زوجه خوزا، ناظر هیرودیس و سوسن و بسیاری از زنان دیگرکه از اموال خود او را خدمت می‌کردند."},{"v":4,"t":"و چون گروهی بسیار فراهم می‌شدند و از هرشهر نزد او می‌آمدند مثلی آورده، گفت"},{"v":5,"t":"که «برزگری بجهت تخم کاشتن بیرون رفت. و وقتی که تخم می‌کاشت بعضی بر کناره راه ریخته شد وپایمال شده، مرغان هوا آن را خوردند."},{"v":6,"t":"وپاره‌ای بر سنگلاخ افتاده چون رویید از آنجهت که رطوبتی نداشت خشک گردید."},{"v":7,"t":"و قدری درمیان خارها افکنده شد که خارها با آن نمو کرده آن را خفه نمود."},{"v":8,"t":"و بعضی در زمین نیکو پاشیده شده رویید و صد چندان ثمر آورد.» چون این بگفت ندا در‌داد «هر‌که گوش شنوا دارد بشنود.»"},{"v":9,"t":"پس شاگردانش از او سوال نموده، گفتند که «معنی‌این مثل چیست؟»"},{"v":10,"t":"گفت: «شما رادانستن اسرار ملکوت خدا عطا شده است و لیکن دیگران را به واسطه مثلها، تا نگریسته نبینند وشنیده درک نکنند."},{"v":11,"t":"اما مثل این است که تخم کلام خداست."},{"v":12,"t":"و آنانی که در کنار راه هستندکسانی می‌باشند که چون می‌شنوند، فور ابلیس آمده کلام را از دلهای ایشان می‌رباید، مبادا ایمان آورده نجات یابند."},{"v":13,"t":"و آنانی که بر سنگلاخ هستند کسانی می‌باشند که چون کلام رامی شنوند آن را به شادی می‌پذیرند و اینها ریشه ندارند پس تا مدتی ایمان می‌دارند و در وقت آزمایش، مرتد می‌شوند."},{"v":14,"t":"اما آنچه در خارهاافتاد اشخاصی می‌باشند که چون شنوند می‌روند و اندیشه های روزگار و دولت و لذات آن ایشان راخفه می‌کند و هیچ میوه به‌کمال نمی رسانند."},{"v":15,"t":"اما آنچه در زمین نیکو واقع گشت کسانی می‌باشند که کلام را به دل راست و نیکو شنیده، آن را نگاه می‌دارند و با صبر، ثمر می‌آورند."},{"v":16,"t":"«و هیچ‌کس چراغ را افروخته، آن را زیرظرفی یا تختی پنهان نمی کند بلکه بر چراغدان می‌گذارد تا هر‌که داخل شود روشنی را ببیند."},{"v":17,"t":"زیرا چیزی نهان نیست که ظاهر نگردد و نه مستور که معلوم و هویدا نشود."},{"v":18,"t":"پس احتیاطنمایید که به چه طور می‌شنوید، زیرا هر‌که داردبدو داده خواهد شد و از آنکه ندارد آنچه گمان هم می‌برد که دارد، از او گرفته خواهد شد.»"},{"v":19,"t":"و مادر وبرادران او نزد وی آمده به‌سبب ازدحام خلق نتوانستند او را ملاقات کنند."},{"v":20,"t":"پس او را خبر داده گفتند: «مادر و برادرانت بیرون ایستاده می‌خواهند تو را ببینند.»"},{"v":21,"t":"در جواب ایشان گفت: «مادر و برادران من اینانند که کلام خدا را شنیده آن را به‌جا می‌آورند.»"},{"v":22,"t":"روزی از روزها او با شاگردان خود به کشتی سوار شده، به ایشان گفت: «به سوی آن کناردریاچه عبور بکنیم.» پس کشتی را حرکت دادند."},{"v":23,"t":"و چون می‌رفتند، خواب او را در ربود که ناگاه طوفان باد بر دریاچه فرود آمد، بحدی که کشتی از آب پر می‌شد و ایشان در خطر افتادند."},{"v":24,"t":"پس نزد او آمده او را بیدار کرده، گفتند: «استادا، استادا، هلاک می‌شویم.» پس برخاسته باد وتلاطم آب را نهیب داد تا ساکن گشت و آرامی پدید آمد."},{"v":25,"t":"پس به ایشان گفت: «ایمان شما کجااست؟» ایشان ترسان و متعجب شده با یکدیگرمی گفتند که «این چطور آدمی است که بادها وآب را هم امر می‌فرماید و اطاعت او می‌کنند.»"},{"v":26,"t":"و به زمین جدریان که مقابل جلیل است، رسیدند."},{"v":27,"t":"چون به خشکی فرود آمد، ناگاه شخصی از آن شهر‌که از مدت مدیدی دیوهاداشتی و رخت نپوشیدی و در خانه نماندی بلکه در قبرها منزل داشتی دچار وی گردید."},{"v":28,"t":"چون عیسی را دید، نعره زد و پیش او افتاده به آواز بلندگفت: «ای عیسی پسر خدای تعالی، مرا با تو چه‌کار است؟ از تو التماس دارم که مرا عذاب ندهی.»"},{"v":29,"t":"زیرا که روح خبیث را امر فرموده بودکه از آن شخص بیرون آید. چونکه بارها او راگرفته بود، چنانکه هر‌چند او را به زنجیرها وکنده‌ها بسته نگاه می‌داشتند، بندها را می‌گسیخت و دیو او را به صحرا می‌راند."},{"v":30,"t":"عیسی از اوپرسیده، گفت: «نام تو چیست؟» گفت: «لجئون.» زیرا که دیوهای بسیار داخل او شده بودند."},{"v":31,"t":"واز او استدعا کردند که ایشان را نفرماید که به هاویه روند."},{"v":32,"t":"و در آن نزدیکی گله گراز بسیاری بودند که در کوه می‌چریدند. پس از او خواهش نمودند که بدیشان اجازت دهد تا در آنها داخل شوند. پس ایشان را اجازت داد."},{"v":33,"t":"ناگاه دیوها از آن آدم بیرون شده، داخل گرازان گشتند که آن گله ازبلندی به دریاچه جسته، خفه شدند."},{"v":34,"t":"چون گرازبانان ماجرا را دیدند فرار کردند و در شهر واراضی آن شهرت دادند."},{"v":35,"t":"پس مردم بیرون آمده تا آن واقعه را ببینندنزد عیسی رسیدند و چون آدمی را که از او دیوهابیرون رفته بودند، دیدند که نزد پایهای عیسی رخت پوشیده و عاقل گشته نشسته است ترسیدند."},{"v":36,"t":"و آنانی که این را دیده بودند ایشان راخبر دادند که آن دیوانه چطور شفا یافته بود."},{"v":37,"t":"پس تمام خلق مرزوبوم جدریان از او خواهش نمودند که از نزد ایشان روانه شود، زیرا خوفی شدید بر ایشان مستولی شده بود. پس او به کشتی سوار شده مراجعت نمود."},{"v":38,"t":"اما آن شخصی که دیوها از وی بیرون رفته بودند از او درخواست کرد که با وی باشد. لیکن عیسی او را روانه فرموده، گفت:"},{"v":39,"t":"«به خانه خود برگرد و آنچه خدا با تو کرده است حکایت کن.» پس رفته درتمام شهر از آنچه عیسی بدو نموده بود موعظه کرد."},{"v":40,"t":"و چون عیسی مراجعت کرد خلق او راپذیرفتند زیرا جمیع مردم چشم به راه اومی داشتند."},{"v":41,"t":"که ناگاه مردی، یایرس نام که رئیس کنیسه بود به پایهای عیسی افتاده، به اوالتماس نمود که به خانه او بیاید."},{"v":42,"t":"زیرا که او رادختر یگانه‌ای قریب به دوازده ساله بود که مشرف بر موت بود. و چون می‌رفت خلق بر اوازدحام می‌نمودند."},{"v":43,"t":"ناگاه زنی که مدت دوازده سال به استحاضه مبتلا بود و تمام مایملک خود را صرف اطبانموده و هیچ‌کس نمی توانست او را شفا دهد،"},{"v":44,"t":"از پشت سر وی آمده، دامن ردای او را لمس نمود که در ساعت جریان خونش ایستاد."},{"v":45,"t":"پس عیسی گفت: «کیست که مرا لمس نمود.» چون همه انکار کردند، پطرس و رفقایش گفتند: «ای استاد مردم هجوم آورده بر تو ازدحام می‌کنند ومی گویی کیست که مرا لمس نمود؟»"},{"v":46,"t":"عیسی گفت: «البته کسی مرا لمس نموده است، زیرا که من درک کردم که قوتی از من بیرون شد.»"},{"v":47,"t":"چون آن زن دید که نمی تواند پنهان ماند، لرزان شده، آمد و نزد وی افتاده پیش همه مردم گفت که به چه سبب او را لمس نمود و چگونه فور شفا یافت."},{"v":48,"t":"وی را گفت: «ای دختر خاطرجمع دار، ایمانت تو را شفا داده است، به سلامتی برو.»"},{"v":49,"t":"و این سخن هنوز بر زبان او بود که یکی ازخانه رئیس کنیسه آمده به وی گفت: «دخترت مرد. دیگر استاد را زحمت مده.»"},{"v":50,"t":"چون عیسی این را شنید توجه نموده به وی گفت: «ترسان مباش، ایمان آور و بس که شفا خواهد یافت.»"},{"v":51,"t":"و چون داخل خانه شد، جز پطرس و یوحنا ویعقوب و پدر و مادر دختر هیچ‌کس را نگذاشت که به اندرون آید."},{"v":52,"t":"و چون همه برای او گریه وزاری می‌کردند او گفت: «گریان مباشید نمرده بلکه خفته است.»"},{"v":53,"t":"پس به او استهزا کردندچونکه می‌دانستند که مرده است."},{"v":54,"t":"پس او همه را بیرون کرد و دست دختر را گرفته صدا زد وگفت: «ای دختر برخیز.»"},{"v":55,"t":"و روح او برگشت وفور برخاست. پس عیسی فرمود تا به وی خوراک دهند."},{"v":56,"t":"و پدر و مادر او حیران شدند. پس ایشان را فرمود که هیچ‌کس را از این ماجراخبر ندهند."}],"en":[{"v":1,"t":"Soon afterwards, he went about through cities and villages, preaching and bringing the good news of God’s Kingdom. With him were the twelve,"},{"v":2,"t":"and certain women who had been healed of evil spirits and infirmities: Mary who was called Magdalene, from whom seven demons had gone out;"},{"v":3,"t":"and Joanna, the wife of Chuzas, Herod’s steward; Susanna; and many others who served them from their possessions."},{"v":4,"t":"When a great multitude came together and people from every city were coming to him, he spoke by a parable:"},{"v":5,"t":"“The farmer went out to sow his seed. As he sowed, some fell along the road, and it was trampled under foot, and the birds of the sky devoured it."},{"v":6,"t":"Other seed fell on the rock, and as soon as it grew, it withered away, because it had no moisture."},{"v":7,"t":"Other fell amid the thorns, and the thorns grew with it and choked it."},{"v":8,"t":"Other fell into the good ground and grew and produced one hundred times as much fruit.” As he said these things, he called out, “He who has ears to hear, let him hear!”"},{"v":9,"t":"Then his disciples asked him, “What does this parable mean?”"},{"v":10,"t":"He said, “To you it is given to know the mysteries of God’s Kingdom, but to the rest it is given in parables, that ‘seeing they may not see, and hearing they may not understand.’"},{"v":11,"t":"“Now the parable is this: The seed is the word of God."},{"v":12,"t":"Those along the road are those who hear; then the devil comes and takes away the word from their heart, that they may not believe and be saved."},{"v":13,"t":"Those on the rock are they who, when they hear, receive the word with joy; but these have no root. They believe for a while, then fall away in time of temptation."},{"v":14,"t":"What fell among the thorns, these are those who have heard, and as they go on their way they are choked with cares, riches, and pleasures of life; and they bring no fruit to maturity."},{"v":15,"t":"Those in the good ground, these are those who with an honest and good heart, having heard the word, hold it tightly, and produce fruit with perseverance."},{"v":16,"t":"“No one, when he has lit a lamp, covers it with a container or puts it under a bed; but puts it on a stand, that those who enter in may see the light."},{"v":17,"t":"For nothing is hidden that will not be revealed, nor anything secret that will not be known and come to light."},{"v":18,"t":"Be careful therefore how you hear. For whoever has, to him will be given; and whoever doesn’t have, from him will be taken away even that which he thinks he has.”"},{"v":19,"t":"His mother and brothers came to him, and they could not come near him for the crowd."},{"v":20,"t":"Some people told him, “Your mother and your brothers stand outside, desiring to see you.”"},{"v":21,"t":"But he answered them, “My mother and my brothers are these who hear the word of God and do it.”"},{"v":22,"t":"Now on one of those days, he entered into a boat, himself and his disciples, and he said to them, “Let’s go over to the other side of the lake.” So they launched out."},{"v":23,"t":"But as they sailed, he fell asleep. A wind storm came down on the lake, and they were taking on dangerous amounts of water."},{"v":24,"t":"They came to him and awoke him, saying, “Master, Master, we are dying!” He awoke and rebuked the wind and the raging of the water; then they ceased, and it was calm."},{"v":25,"t":"He said to them, “Where is your faith?” Being afraid, they marveled, saying to one another, “Who is this then, that he commands even the winds and the water, and they obey him?”"},{"v":26,"t":"Then they arrived at the country of the Gadarenes, which is opposite Galilee."},{"v":27,"t":"When Jesus stepped ashore, a certain man out of the city who had demons for a long time met him. He wore no clothes, and didn’t live in a house, but in the tombs."},{"v":28,"t":"When he saw Jesus, he cried out and fell down before him, and with a loud voice said, “What do I have to do with you, Jesus, you Son of the Most High God? I beg you, don’t torment me!”"},{"v":29,"t":"For Jesus was commanding the unclean spirit to come out of the man. For the unclean spirit had often seized the man. He was kept under guard and bound with chains and fetters. Breaking the bonds apart, he was driven by the demon into the desert."},{"v":30,"t":"Jesus asked him, “What is your name?” He said, “Legion,” for many demons had entered into him."},{"v":31,"t":"They begged him that he would not command them to go into the abyss."},{"v":32,"t":"Now there was there a herd of many pigs feeding on the mountain, and they begged him that he would allow them to enter into those. Then he allowed them."},{"v":33,"t":"The demons came out of the man and entered into the pigs, and the herd rushed down the steep bank into the lake and were drowned."},{"v":34,"t":"When those who fed them saw what had happened, they fled and told it in the city and in the country."},{"v":35,"t":"People went out to see what had happened. They came to Jesus and found the man from whom the demons had gone out, sitting at Jesus’ feet, clothed and in his right mind; and they were afraid."},{"v":36,"t":"Those who saw it told them how he who had been possessed by demons was healed."},{"v":37,"t":"All the people of the surrounding country of the Gadarenes asked him to depart from them, for they were very much afraid. Then he entered into the boat and returned."},{"v":38,"t":"But the man from whom the demons had gone out begged him that he might go with him, but Jesus sent him away, saying,"},{"v":39,"t":"“Return to your house, and declare what great things God has done for you.” He went his way, proclaiming throughout the whole city what great things Jesus had done for him."},{"v":40,"t":"When Jesus returned, the multitude welcomed him, for they were all waiting for him."},{"v":41,"t":"Behold, a man named Jairus came. He was a ruler of the synagogue. He fell down at Jesus’ feet and begged him to come into his house,"},{"v":42,"t":"for he had an only born daughter, about twelve years of age, and she was dying. But as he went, the multitudes pressed against him."},{"v":43,"t":"A woman who had a flow of blood for twelve years, who had spent all her living on physicians and could not be healed by any,"},{"v":44,"t":"came behind him and touched the fringe of his cloak. Immediately the flow of her blood stopped."},{"v":45,"t":"Jesus said, “Who touched me?” When all denied it, Peter and those with him said, “Master, the multitudes press and jostle you, and you say, ‘Who touched me?’”"},{"v":46,"t":"But Jesus said, “Someone did touch me, for I perceived that power has gone out of me.”"},{"v":47,"t":"When the woman saw that she was not hidden, she came trembling; and falling down before him declared to him in the presence of all the people the reason why she had touched him, and how she was healed immediately."},{"v":48,"t":"He said to her, “Daughter, cheer up. Your faith has made you well. Go in peace.”"},{"v":49,"t":"While he still spoke, one from the ruler of the synagogue’s house came, saying to him, “Your daughter is dead. Don’t trouble the Teacher.”"},{"v":50,"t":"But Jesus hearing it, answered him, “Don’t be afraid. Only believe, and she will be healed.”"},{"v":51,"t":"When he came to the house, he didn’t allow anyone to enter in, except Peter, John, James, the father of the child, and her mother."},{"v":52,"t":"All were weeping and mourning her, but he said, “Don’t weep. She isn’t dead, but sleeping.”"},{"v":53,"t":"They were ridiculing him, knowing that she was dead."},{"v":54,"t":"But he put them all outside, and taking her by the hand, he called, saying, “Child, arise!”"},{"v":55,"t":"Her spirit returned, and she rose up immediately. He commanded that something be given to her to eat."},{"v":56,"t":"Her parents were amazed, but he commanded them to tell no one what had been done."}],"hr":[{"v":1,"t":"Zatim zareda obilaziti gradom i selom propovijedajući i navješćujući evanđelje o kraljevstvu Božjemu. Bila su s njim dvanaestorica"},{"v":2,"t":"i neke žene koje bijahu izliječene od zlih duhova i bolesti: Marija zvana Magdalena, iz koje bijaše izagnao sedam đavola;"},{"v":3,"t":"zatim Ivana, žena Herodova upravitelja Huze; Suzana i mnoge druge. One su im posluživale od svojih dobara."},{"v":4,"t":"Kad se skupio silan svijet te iz svakoga grada nagrnuše k njemu, prozbori u prispodobi:"},{"v":5,"t":"“Iziđe sijač sijati sjeme. Dok je sijao, jedno pade uz put, bi pogaženo i ptice ga nebeske pozobaše."},{"v":6,"t":"Drugo pade na kamen i, tek što je izniklo, osuši se jer ne imaše vlage."},{"v":7,"t":"Drugo opet pade među trnje i trnje ga preraste i uguši."},{"v":8,"t":"Drugo napokon pade u dobru zemlju, nikne i urodi stostrukim plodom.” Rekavši to, povika: “Tko ima uši da čuje, neka čuje!”"},{"v":9,"t":"Upitaše ga učenici kakva bi to bila prispodoba."},{"v":10,"t":"A on im reče: “Vama je dano znati otajstva kraljevstva Božjega, a ostalima u prispodobama - da gledajući ne vide i slušajući ne razumiju.”"},{"v":11,"t":"“A ovo je prispodoba: Sjeme je Riječ Božja."},{"v":12,"t":"Oni uz put slušatelji su. Zatim dolazi đavao i odnosi Riječ iz srca njihova da ne bi povjerovali i spasili se."},{"v":13,"t":"A na kamenu - to su oni koji kad čuju, s radošću prime Riječ, ali korijena nemaju: ti neko vrijeme vjeruju, a u vrijeme kušnje otpadnu."},{"v":14,"t":"A što pade u trnje - to su oni koji poslušaju, ali poneseni brigama, bogatstvom i nasladama života, uguše se i ne dorode roda."},{"v":15,"t":"Ono pak u dobroj zemlji - to su oni koji u plemenitu i dobru srcu slušaju Riječ, zadrže je i donose rod u ustrajnosti.”"},{"v":16,"t":"“Nitko ne užiže svjetiljke da je pokrije posudom ili stavi pod postelju, nego je stavlja na svijećnjak da oni koji ulaze vide svjetlost."},{"v":17,"t":"Ta ništa nije tajno što se neće očitovati; ništa skriveno što se neće saznati i na vidjelo doći.”"},{"v":18,"t":"“Pazite dakle kako slušate. Doista, onomu tko ima dat će se, a onomu tko nema oduzet će se i ono što misli da ima.”"},{"v":19,"t":"A majka i braća njegova htjedoše k njemu, ali ne mogoše do njega zbog mnoštva."},{"v":20,"t":"Javiše mu: “Majka tvoja i braća tvoja stoje vani i žele te vidjeti.”"},{"v":21,"t":"A on im odgovori: “Majka moja, braća moja - ovi su koji riječ Božju slušaju i vrše.”"},{"v":22,"t":"Jednoga dana uđe u lađu on i učenici njegovi. I reče im: “Prijeđimo na onu stranu jezera.” I otisnuše se."},{"v":23,"t":"Dok su plovili, on zaspa. I spusti se oluja na jezero. Voda stane nadirati te bijahu u pogibli."},{"v":24,"t":"Oni pristupiše i probudiše ga govoreći: “Učitelju, učitelju, propadosmo!” On se probudi, zaprijeti vjetru i valovlju; i oni se smire te nasta utiha."},{"v":25,"t":"A on će im: “Gdje vam je vjera?” A oni se prestrašeni u čudu zapitkivahu: “Tko li je ovaj da i vjetrovima zapovijeda i vodi, i pokoravaju mu se?”"},{"v":26,"t":"Doploviše u gergezenski kraj koji je nasuprot Galileji."},{"v":27,"t":"Čim iziđe na kopno, eto mu iz grada u susret nekog čovjeka koji imaše zloduhe. Već dugo vremena nije se uopće odijevao niti stanovao u kući, nego po grobnicama."},{"v":28,"t":"Kad opazi Isusa, zastenja, pade ničice preda nj i u sav glas povika: “Što ti imaš sa mnom, Isuse, Sine Boga Svevišnjega? Molim te, ne muči me!”"},{"v":29,"t":"Jer bijaše zapovjedio nečistom duhu da iziđe iz toga čovjeka. Da, dugo ga je već vremena držao u vlasti i makar su ga lancima vezali i u verigama čuvali, on bi raskidao spone i zloduh bi ga odagnao u pustinju."},{"v":30,"t":"Isus ga nato upita: “Kako ti je ime?” On reče: “Legija”, jer u nj uđoše mnogi zlodusi."},{"v":31,"t":"I zaklinjahu ga da im ne naredi vratiti se u Bezdan."},{"v":32,"t":"A ondje u gori paslo je poveliko krdo svinja. Zaklinjahu ga dakle da im dopusti ući u njih. I on im dopusti."},{"v":33,"t":"Tada zlodusi iziđoše iz čovjeka i uđoše u svinje. Krdo jurnu niz obronak u jezero i podavi se."},{"v":34,"t":"Vidjevši što se dogodilo, svinjari pobjegoše i razglasiše gradom i selima."},{"v":35,"t":"A ljudi iziđoše vidjeti što se dogodilo. Dođoše Isusu i nađoše čovjeka iz kojega bijahu izašli zlodusi gdje do nogu Isusovih sjedi, obučen i zdrave pameti. I prestraše se."},{"v":36,"t":"A očevici im ispripovijediše kako je opsjednuti ozdravio."},{"v":37,"t":"I zamoli ga sve ono mnoštvo iz okolice gergezenske da ode od njih jer ih strah velik spopade. On uđe u lađu i vrati se."},{"v":38,"t":"A moljaše ga čovjek iz koga iziđoše zlodusi da može ostati s njim, ali ga on otpusti govoreći:"},{"v":39,"t":"“Vrati se kući i pripovijedaj što ti učini Bog.” On ode razglašujući po svem gradu što mu učini Isus."},{"v":40,"t":"Na povratku Isusa dočeka mnoštvo jer su ga svi željno iščekivali."},{"v":41,"t":"I gle, dođe čovjek, ime mu Jair, koji bijaše predstojnik sinagoge. Baci se Isusu pred noge i stane ga moliti da dođe u njegovu kuću."},{"v":42,"t":"Imaše kćer jedinicu, otprilike od dvanaest godina, koja umiraše. Dok je onamo išao, mnoštvo ga guralo odasvud."},{"v":43,"t":"A neka žena koja je već dvanaest godina bolovala od krvarenja, sve svoje imanje potrošila na liječnike i nitko je nije mogao izliječiti,"},{"v":44,"t":"priđe odostrag i dotaknu se skuta njegove haljine i umah joj se zaustavi krvarenje."},{"v":45,"t":"I reče Isus: “Tko me se to dotaknu?” Svi se branili, a Petar će: “Učitelju, mnoštvo te gura i pritišće.”"},{"v":46,"t":"A Isus: “Netko me se dotaknuo. Osjetio sam kako snaga izlazi iz mene.”"},{"v":47,"t":"A žena, vidjevši da se ne može kriti, sva u strahu pristupi i baci se preda nj te pred svim narodom ispripovjedi zašto ga se dotakla i kako je umah ozdravila."},{"v":48,"t":"A on joj reče: “Kćeri, vjera te tvoja spasila. Idi u miru!”"},{"v":49,"t":"Dok je on još govorio, eto jednog od nadstojnikovih s porukom: “Umrla ti kći, ne muči više Učitelja.”"},{"v":50,"t":"Čuo to Isus pa mu reče: “Ne boj se! Samo vjeruj i ona će se spasiti!”"},{"v":51,"t":"Uđe u kuću, ali nikomu ne dopusti da s njim uđe osim Petra, Ivana, Jakova i djetetova oca i majke."},{"v":52,"t":"A svi plakahu i žalovahu za njom. A on im reče: “Ne plačite! Nije umrla, nego spava!”"},{"v":53,"t":"No oni mu se podsmjehivahu znajući da je umrla."},{"v":54,"t":"On je uhvati za ruku i povika: “Dijete, ustani!”"},{"v":55,"t":"I povrati joj se duh i umah ustade, a on naredi da joj dadu jesti."},{"v":56,"t":"Njezini se roditelji začudiše, a on zapovjedi da nikome ne reknu što se dogodilo."}]},"9":{"fa":[{"v":1,"t":"پس دوازده شاگرد خود را طلبیده، به ایشان قوت و قدرت بر جمیع دیوها و شفادادن امراض عطا فرمود."},{"v":2,"t":"و ایشان را فرستاد تا به ملکوت خدا موعظه کنند و مریضان را صحت بخشند."},{"v":3,"t":"و بدیشان گفت: «هیچ‌چیز بجهت راه برمدارید نه عصا و نه توشه‌دان و نه نان و نه پول ونه برای یک نفر دو جامه."},{"v":4,"t":"و به هرخانه‌ای که داخل شوید همان جا بمانید تا از آن موضع روانه شوید."},{"v":5,"t":"و هر‌که شما را نپذیرد، وقتی که از آن شهر بیرون شوید خاک پایهای خود را نیزبیفشانید تا بر ایشان شهادتی شود.»"},{"v":6,"t":"پس بیرون شده در دهات می‌گشتند و بشارت می‌دادند و درهرجا صحت می‌بخشیدند."},{"v":7,"t":"اما هیرودیس تیترارک، چون خبر تمام این وقایع را شنید مضطرب شد، زیرا بعضی می‌گفتندکه یحیی از مردگان برخاسته است،"},{"v":8,"t":"و بعضی که الیاس ظاهر شده و دیگران، که یکی از انبیای پیشین برخاسته است."},{"v":9,"t":"اما هیرودیس گفت «سریحیی را از تنش من جدا کردم ولی این کیست که درباره او چنین خبر می‌شنوم» و طالب ملاقات وی می‌بود."},{"v":10,"t":"و چون رسولان مراجعت کردند، آنچه کرده بودند بدو بازگفتند. پس ایشان را برداشته به ویرانه‌ای نزدیک شهری که بیت صیدا نام داشت به خلوت رفت."},{"v":11,"t":"اما گروهی بسیار اطلاع یافته در عقب وی شتافتند. پس ایشان را پذیرفته، ایشان را از ملکوت خدا اعلام می‌نمود و هر‌که احتیاج به معالجه می‌داشت صحت می‌بخشید."},{"v":12,"t":"و چون روز رو به زوال نهاد، آن دوازده نزدوی آمده، گفتند: «مردم را مرخص فرما تا به دهات و اراضی این حوالی رفته منزل و خوراک برای خویشتن پیدا نمایند، زیرا که در اینجا درصحرا می‌باشیم.»"},{"v":13,"t":"او بدیشان گفت: «شماایشان را غذا دهید.» گفتند: «ما را جز پنج نان و دوماهی نیست مگر برویم و بجهت جمیع این گروه غدا بخریم.»"},{"v":14,"t":"زیرا قریب به پنجهزار مرد بودند. پس به شاگردان خود گفت که ایشان را پنجاه پنجاه، دسته دسته، بنشانند.»"},{"v":15,"t":"ایشان همچنین کرده همه را نشانیدند."},{"v":16,"t":"پس آن پنج نان و دوماهی را گرفته، به سوی آسمان نگریست و آنها رابرکت داده، پاره نمود و به شاگردان خود داد تاپیش مردم گذارند."},{"v":17,"t":"پس همه خورده سیرشدند. و دوازده سبد پر از پاره های باقی‌مانده برداشتند."},{"v":18,"t":"و هنگامی که او به تنهایی دعا می‌کرد وشاگردانش همراه او بودند، از ایشان پرسیده، گفت: «مردم مرا که می‌دانند؟»"},{"v":19,"t":"در جواب گفتند: «یحیی تعمید‌دهنده و بعضی الیاس ودیگران می‌گویند که یکی از انبیای پیشین برخاسته است.»"},{"v":20,"t":"بدیشان گفت: «شما مرا که می‌دانید؟» پطرس در جواب گفت: «مسیح خدا.»"},{"v":21,"t":"پس ایشان را قدغن بلیغ فرمود که هیچ‌کس را از این اطلاع مدهید."},{"v":22,"t":"و گفت: «لازم است که پسر انسان زحمت بسیار بیند و از مشایخ وروسای کهنه و کاتبان رد شده کشته شود و روزسوم برخیزد.»"},{"v":23,"t":"پس به همه گفت: «اگر کسی بخواهد مراپیروی کند می‌باید نفس خود را انکار نموده، صلیب خود را هر روزه بردارد و مرا متابعت کند."},{"v":24,"t":"زیرا هر‌که بخواهد جان خود را خلاصی دهدآن را هلاک سازد و هر کس جان خود را بجهت من تلف کرد، آن را نجات خواهد داد."},{"v":25,"t":"زیراانسان را چه فایده دارد که تمام جهان را ببرد ونفس خود را بر باد دهد یا آن را زیان رساند."},{"v":26,"t":"زیرا هر‌که از من و کلام من عار دارد پسر انسان نیز وقتی که در جلال خود و جلال پدر و ملائکه مقدسه آید از او عار خواهد داشت."},{"v":27,"t":"لیکن هرآینه به شما می‌گویم که بعضی از حاضرین دراینجا هستند که تا ملکوت خدا را نبینند ذائقه موت را نخواهند چشید.»"},{"v":28,"t":"و از این کلام قریب به هشت روز گذشته بود که پطرس و یوحنا و یعقوب را برداشته برفراز کوهی برآمد تا دعا کند."},{"v":29,"t":"و چون دعامی کرد هیات چهره او متبدل گشت و لباس اوسفید و درخشان شد."},{"v":30,"t":"که ناگاه دو مرد یعنی موسی و الیاس با وی ملاقات کردند."},{"v":31,"t":"و به هیات جلالی ظاهر شده درباره رحلت او که می‌بایست به زودی در اورشلیم واقع شود گفتگومی کردند."},{"v":32,"t":"اما پطرس و رفقایش را خواب در ربود. پس بیدار شده جلال او و آن دو مرد را که با وی بودند، دیدند."},{"v":33,"t":"و چون آن دو نفر از او جدامی شدند، پطرس به عیسی گفت که «ای استاد، بودن ما در اینجا خوب است. پس سه سایبان بسازیم یکی برای تو و یکی برای موسی ودیگری برای الیاس.» زیرا که نمی دانست چه می‌گفت."},{"v":34,"t":"و این سخن هنوز بر زبانش می‌بود که ناگاه ابری پدیدار شده بر ایشان سایه افکند وچون داخل ابر می‌شدند، ترسان گردیدند."},{"v":35,"t":"آنگاه صدایی از ابر برآمد که «این است پسرحبیب من، او را بشنوید.»"},{"v":36,"t":"و چون این آوازرسید عیسی را تنها یافتند و ایشان ساکت ماندندو از آنچه دیده بودند هیچ‌کس را در آن ایام خبرندادند."},{"v":37,"t":"و در روز بعد چون ایشان از کوه به زیرآمدند، گروهی بسیار او را استقبال نمودند."},{"v":38,"t":"که ناگاه مردی از آن میان فریادکنان گفت: «ای استادبه تو التماس می‌کنم که بر پسر من لطف فرمایی زیرا یگانه من است."},{"v":39,"t":"که ناگاه روحی او رامی گیرد و دفعه صیحه می‌زند و کف کرده مصروع می‌شود و او را فشرده به دشواری رها می‌کند."},{"v":40,"t":"و از شاگردانت درخواست کردم که او را بیرون کنند نتوانستند.»"},{"v":41,"t":"عیسی در جواب گفت: «ای فرقه بی‌ایمان کج روش، تا کی با شما باشم و متحمل شما گردم. پسر خود را اینجا بیاور.»"},{"v":42,"t":"و چون او می‌آمددیو او را دریده مصروع نمود. اما عیسی آن روح خبیث را نهیب داده طفل را شفا بخشید وبه پدرش سپرد."},{"v":43,"t":"و همه از بزرگی خدامتحیر شدند و وقتی که همه از تمام اعمال عیسی متعجب شدند به شاگردان خودگفت:"},{"v":44,"t":"«این سخنان را در گوشهای خود فراگیریدزیرا که پسر انسان به‌دستهای مردم تسلیم خواهدشد.»"},{"v":45,"t":"ولی این سخن را درک نکردند و از ایشان مخفی داشته شد که آن را نفهمند و ترسیدند که آن را از وی بپرسند."},{"v":46,"t":"و در میان ایشان مباحثه شد که کدام‌یک ازما بزرگتر است."},{"v":47,"t":"عیسی خیال دل ایشان راملتفت شده طفلی بگرفت و او را نزد خود برپاداشت."},{"v":48,"t":"و به ایشان گفت: «هر‌که این طفل را به نام من قبول کند، مرا قبول کرده باشد و هر‌که مراپذیرد، فرستنده مرا پذیرفته باشد. زیرا هر‌که ازجمیع شما کوچکتر باشد، همان بزرگ خواهدبود.»"},{"v":49,"t":"یوحنا جواب داده گفت: «ای استادشخصی را دیدیم که به نام تو دیوها را اخراج می‌کند و او را منع نمودیم، از آن رو که پیروی مانمی کند.»"},{"v":50,"t":"عیسی بدو گفت: «او را ممانعت مکنید. زیرا هر‌که ضد شما نیست با شماست.»"},{"v":51,"t":"و چون روزهای صعود او نزدیک می‌شدروی خود را به عزم ثابت به سوی اورشلیم نهاد."},{"v":52,"t":"پس رسولان پیش از خود فرستاده، ایشان رفته به بلدی از بلاد سامریان وارد گشتند تا برای اوتدارک بینند."},{"v":53,"t":"اما او را جای ندادند از آن رو که عازم اورشلیم می‌بود."},{"v":54,"t":"و چون شاگردان او، یعقوب و یوحنا این را دیدند گفتند: «ای خداوند آیا می‌خواهی بگوییم که آتش از آسمان باریده اینها را فرو‌گیرد چنانکه الیاس نیز کرد؟"},{"v":55,"t":"آنگاه روی گردانیده بدیشان گفت: «نمی دانید که شما ازکدام نوع روح هستید."},{"v":56,"t":"زیرا که پسر انسان نیامده است تا جان مردم را هلاک سازد بلکه تانجات دهد.» پس به قریه‌ای دیگر رفتند."},{"v":57,"t":"و هنگامی که ایشان می‌رفتند در اثنای راه شخصی بدو گفت: «خداوندا هر جا روی تو رامتابعت کنم.»"},{"v":58,"t":"عیسی به وی گفت: «روباهان راسوراخها است و مرغان هوا را آشیانه‌ها، لیکن پسر انسان را جای سر نهادن نیست.»"},{"v":59,"t":"و به دیگری گفت: «از عقب من بیا.» گفت: «خداوندااول مرا رخصت ده تا بروم پدر خود را دفن کنم.»"},{"v":60,"t":"عیسی وی را گفت: «بگذار مردگان مردگان خود را دفن کنند. اما تو برو و به ملکوت خداموعظه کن.»"},{"v":61,"t":"و کسی دیگر گفت: «خداوندا تورا پیروی می‌کنم لیکن اول رخصت ده تا اهل خانه خود را وداع نمایم.»"},{"v":62,"t":"عیسی وی را گفت: «کسی‌که دست را به شخم زدن دراز کرده از پشت سر نظر کند، شایسته ملکوت خدا نمی باشد.»"}],"en":[{"v":1,"t":"He called the twelve together and gave them power and authority over all demons, and to cure diseases."},{"v":2,"t":"He sent them out to preach God’s Kingdom and to heal the sick."},{"v":3,"t":"He said to them, “Take nothing for your journey—no staffs, nor wallet, nor bread, nor money. Don’t have two tunics each."},{"v":4,"t":"Into whatever house you enter, stay there, and depart from there."},{"v":5,"t":"As many as don’t receive you, when you depart from that city, shake off even the dust from your feet for a testimony against them.”"},{"v":6,"t":"They departed and went throughout the villages, preaching the Good News and healing everywhere."},{"v":7,"t":"Now Herod the tetrarch heard of all that was done by him; and he was very perplexed, because it was said by some that John had risen from the dead,"},{"v":8,"t":"and by some that Elijah had appeared, and by others that one of the old prophets had risen again."},{"v":9,"t":"Herod said, “I beheaded John, but who is this about whom I hear such things?” He sought to see him."},{"v":10,"t":"The apostles, when they had returned, told him what things they had done. He took them and withdrew apart to a desert region of a city called Bethsaida."},{"v":11,"t":"But the multitudes, perceiving it, followed him. He welcomed them, spoke to them of God’s Kingdom, and he cured those who needed healing."},{"v":12,"t":"The day began to wear away; and the twelve came and said to him, “Send the multitude away, that they may go into the surrounding villages and farms and lodge and get food, for we are here in a deserted place.”"},{"v":13,"t":"But he said to them, “You give them something to eat.” They said, “We have no more than five loaves and two fish, unless we should go and buy food for all these people.”"},{"v":14,"t":"For they were about five thousand men. He said to his disciples, “Make them sit down in groups of about fifty each.”"},{"v":15,"t":"They did so, and made them all sit down."},{"v":16,"t":"He took the five loaves and the two fish, and looking up to the sky, he blessed them, broke them, and gave them to the disciples to set before the multitude."},{"v":17,"t":"They ate and were all filled. They gathered up twelve baskets of broken pieces that were left over."},{"v":18,"t":"As he was praying alone, the disciples were near him, and he asked them, “Who do the multitudes say that I am?”"},{"v":19,"t":"They answered, “‘John the Baptizer,’ but others say, ‘Elijah,’ and others, that one of the old prophets has risen again.”"},{"v":20,"t":"He said to them, “But who do you say that I am?” Peter answered, “The Christ of God.”"},{"v":21,"t":"But he warned them and commanded them to tell this to no one,"},{"v":22,"t":"saying, “The Son of Man must suffer many things, and be rejected by the elders, chief priests, and scribes, and be killed, and the third day be raised up.”"},{"v":23,"t":"He said to all, “If anyone desires to come after me, let him deny himself, take up his cross, and follow me."},{"v":24,"t":"For whoever desires to save his life will lose it, but whoever will lose his life for my sake will save it."},{"v":25,"t":"For what does it profit a man if he gains the whole world, and loses or forfeits his own self?"},{"v":26,"t":"For whoever will be ashamed of me and of my words, of him will the Son of Man be ashamed when he comes in his glory, and the glory of the Father, and of the holy angels."},{"v":27,"t":"But I tell you the truth: There are some of those who stand here who will in no way taste of death until they see God’s Kingdom.”"},{"v":28,"t":"About eight days after these sayings, he took with him Peter, John, and James, and went up onto the mountain to pray."},{"v":29,"t":"As he was praying, the appearance of his face was altered, and his clothing became white and dazzling."},{"v":30,"t":"Behold, two men were talking with him, who were Moses and Elijah,"},{"v":31,"t":"who appeared in glory and spoke of his departure, which he was about to accomplish at Jerusalem."},{"v":32,"t":"Now Peter and those who were with him were heavy with sleep, but when they were fully awake, they saw his glory, and the two men who stood with him."},{"v":33,"t":"As they were parting from him, Peter said to Jesus, “Master, it is good for us to be here. Let’s make three tents: one for you, one for Moses, and one for Elijah,” not knowing what he said."},{"v":34,"t":"While he said these things, a cloud came and overshadowed them, and they were afraid as they entered into the cloud."},{"v":35,"t":"A voice came out of the cloud, saying, “This is my beloved Son. Listen to him!”"},{"v":36,"t":"When the voice came, Jesus was found alone. They were silent, and told no one in those days any of the things which they had seen."},{"v":37,"t":"On the next day, when they had come down from the mountain, a great multitude met him."},{"v":38,"t":"Behold, a man from the crowd called out, saying, “Teacher, I beg you to look at my son, for he is my only born child."},{"v":39,"t":"Behold, a spirit takes him, he suddenly cries out, and it convulses him so that he foams; and it hardly departs from him, bruising him severely."},{"v":40,"t":"I begged your disciples to cast it out, and they couldn’t.”"},{"v":41,"t":"Jesus answered, “Faithless and perverse generation, how long shall I be with you and bear with you? Bring your son here.”"},{"v":42,"t":"While he was still coming, the demon threw him down and convulsed him violently. But Jesus rebuked the unclean spirit, healed the boy, and gave him back to his father."},{"v":43,"t":"They were all astonished at the majesty of God. But while all were marveling at all the things which Jesus did, he said to his disciples,"},{"v":44,"t":"“Let these words sink into your ears, for the Son of Man will be delivered up into the hands of men.”"},{"v":45,"t":"But they didn’t understand this saying. It was concealed from them, that they should not perceive it, and they were afraid to ask him about this saying."},{"v":46,"t":"An argument arose among them about which of them was the greatest."},{"v":47,"t":"Jesus, perceiving the reasoning of their hearts, took a little child, and set him by his side,"},{"v":48,"t":"and said to them, “Whoever receives this little child in my name receives me. Whoever receives me receives him who sent me. For whoever is least among you all, this one will be great.”"},{"v":49,"t":"John answered, “Master, we saw someone casting out demons in your name, and we forbade him, because he doesn’t follow with us.”"},{"v":50,"t":"Jesus said to him, “Don’t forbid him, for he who is not against us is for us.”"},{"v":51,"t":"It came to pass, when the days were near that he should be taken up, he intently set his face to go to Jerusalem"},{"v":52,"t":"and sent messengers before his face. They went and entered into a village of the Samaritans, so as to prepare for him."},{"v":53,"t":"They didn’t receive him, because he was traveling with his face set toward Jerusalem."},{"v":54,"t":"When his disciples, James and John, saw this, they said, “Lord, do you want us to command fire to come down from the sky and destroy them, just as Elijah did?”"},{"v":55,"t":"But he turned and rebuked them, “You don’t know of what kind of spirit you are."},{"v":56,"t":"For the Son of Man didn’t come to destroy men’s lives, but to save them.” They went to another village."},{"v":57,"t":"As they went on the way, a certain man said to him, “I want to follow you wherever you go, Lord.”"},{"v":58,"t":"Jesus said to him, “The foxes have holes and the birds of the sky have nests, but the Son of Man has no place to lay his head.”"},{"v":59,"t":"He said to another, “Follow me!” But he said, “Lord, allow me first to go and bury my father.”"},{"v":60,"t":"But Jesus said to him, “Leave the dead to bury their own dead, but you go and announce God’s Kingdom.”"},{"v":61,"t":"Another also said, “I want to follow you, Lord, but first allow me to say good-bye to those who are at my house.”"},{"v":62,"t":"But Jesus said to him, “No one, having put his hand to the plow and looking back, is fit for God’s Kingdom.”"}],"hr":[{"v":1,"t":"Sazva dvanaestoricu i dade im moć i vlast nad svim zlodusima i da liječe bolesti."},{"v":2,"t":"I posla ih propovijedati kraljevstvo Božje i liječiti bolesnike."},{"v":3,"t":"I reče im: “Ništa ne uzimajte na put: ni štapa, ni torbe, ni kruha, ni srebra! I da niste imali više od dvije haljine!"},{"v":4,"t":"U koju god kuću uđete, ondje ostanite pa odande dalje pođite."},{"v":5,"t":"Gdje vas ne prime, iziđite iz toga grada i stresite prašinu s nogu za svjedočanstvo protiv njih.”"},{"v":6,"t":"Oni krenuše: obilazili su po selima, navješćivali evanđelje i liječili posvuda."},{"v":7,"t":"Dočuo Herod tetrarh sve što se događa te se nađe u nedoumici jer su neki govorili: “Ivan uskrsnu od mrtvih”;"},{"v":8,"t":"drugi: “Pojavio se Ilija”; treći opet: “Ustao je neki od drevnih proroka.”"},{"v":9,"t":"A Herod reče: “Ivanu ja odrubih glavu. Tko je onda ovaj o kom toliko čujem?” I tražio je priliku da ga vidi."},{"v":10,"t":"Apostoli se vrate i ispripovjede što su učinili. Isus ih povede sa sobom i povuče se nasamo u grad zvani Betsaida."},{"v":11,"t":"Saznalo to mnoštvo po pođe za njim. On ih primi te im govoraše o kraljevstvu Božjem i ozdravljaše sve koji su trebali ozdravljenja."},{"v":12,"t":"Dan bijaše na izmaku. Pristupe dakle dvanaestorica pa mu reknu: “Otpusti svijet, neka pođu po okolnim selima i zaseocima da se sklone i nađu jela jer smo ovdje u pustu kraju.”"},{"v":13,"t":"A on im reče: “Podajte im vi jesti!” Oni rekoše: “Nemamo više od pet kruhova i dvije ribe, osim da odemo kupiti hrane za sav ovaj narod.”"},{"v":14,"t":"A bijaše oko pet tisuća muškaraca. Nato će on svojim učenicima: “Posjedajte ih po skupinama, otprilike po pedeset.”"},{"v":15,"t":"I učine tako: sve ih posjedaju."},{"v":16,"t":"A on uze pet kruhova i dvije ribe, pogleda na nebo, blagoslovi ih i razlomi pa davaše učenicima da posluže mnoštvo."},{"v":17,"t":"Jeli su i svi se nasitili. I od preteklih ulomaka nakupilo se dvanaest košara."},{"v":18,"t":"Dok je jednom u osami molio, bijahu s njim samo njegovi učenici. On ih upita: “Što govori svijet, tko sam ja?”"},{"v":19,"t":"Oni odgovoriše: “Da si Ivan Krstitelj, drugi: da si Ilija, treći opet: da neki od drevnih proroka usta.”"},{"v":20,"t":"A on im reče: “A vi, što vi kažete, tko sam ja?” Petar prihvati i reče: “Krist - Pomazanik Božji!”"},{"v":21,"t":"A on im zaprijeti da toga nikomu ne kazuju."},{"v":22,"t":"Reče: “Treba da Sin Čovječji mnogo pretrpi, da ga starješine, glavari svećenički i pismoznanci odbace, da bude ubijen i treći dan da uskrsne.”"},{"v":23,"t":"A govoraše svima: “Hoće li tko za mnom, neka se odrekne samoga sebe, neka danomice uzima križ svoj i neka ide za mnom."},{"v":24,"t":"Tko hoće život svoj spasiti, izgubit će ga; a tko izgubi život svoj poradi mene, taj će ga spasiti."},{"v":25,"t":"Ta što koristi čovjeku ako sav svijet zadobije, a sebe samoga izgubi ili sebi naudi?”"},{"v":26,"t":"“Doista, tko se zastidi mene i mojih riječi, toga će se i Sin Čovječji stidjeti kada dođe u slavi svojoj i Očevoj i svetih anđela.”"},{"v":27,"t":"“A kažem vam uistinu: neki od nazočnih neće okusiti smrti dok ne vide kraljevstva Božjega.”"},{"v":28,"t":"Jedno osam dana nakon tih besjeda povede Isus sa sobom Petra, Ivana i Jakova te uziđe na goru da se pomoli."},{"v":29,"t":"I dok se molio, izgled mu se lica izmijeni, a odjeća sjajem zablista."},{"v":30,"t":"I gle, dva čovjeka razgovarahu s njime. Bijahu to Mojsije i Ilija."},{"v":31,"t":"Ukazali se u slavi i razgovarali s njime o njegovu Izlasku, što se doskora imao ispuniti u Jeruzalemu."},{"v":32,"t":"No Petra i njegove drugove bijaše svladao san. Kad se probudiše, ugledaše njegovu slavu i dva čovjeka koji stajahu uza nj."},{"v":33,"t":"I dok su oni odlazili od njega, reče Petar Isusu: “Učitelju, dobro nam je ovdje biti. Načinimo tri sjenice: jednu tebi, jednu Mojsiju, jednu Iliji.” Nije znao što govori."},{"v":34,"t":"Dok je on to govorio, pojavi se oblak i zasjeni ih. Ušavši u oblak, oni se prestrašiše."},{"v":35,"t":"A glas se začu iz oblaka: “Ovo je Sin moj, Izabranik! Njega slušajte!”"},{"v":36,"t":"I upravo kad se začu glas, osta Isus sam. Oni su šutjeli i nikomu onih dana nisu kazivali što su vidjeli."},{"v":37,"t":"A kad su sutradan sišli s gore, pohiti mu u susret silan svijet."},{"v":38,"t":"I gle, čovjek neki iz mnoštva povika: “Učitelju, molim te pogledaj mi sina: jedinac mi je,"},{"v":39,"t":"a gle, duh ga spopada te on odmah udari u kriku; trza njime i on se pjeni te jedva da od njega odstupi dok ga nije posve satro."},{"v":40,"t":"Molio sam tvoje učenike da ga izagnaju, ali ne mogoše.”"},{"v":41,"t":"Isus odvrati: “O rode nevjerni i opaki, dokle mi je biti s vama i podnositi vas? Dovedi ovamo svoga sina!”"},{"v":42,"t":"I dok je prilazio, obori ga zloduh i potrese. A Isus zaprijeti nečistom duhu te izliječi dječaka i preda ga njegovu ocu."},{"v":43,"t":"Svi se zapanjiše zbog veličanstva Božjega. Dok su se svi divili svemu što je činio, reče on učenicima:"},{"v":44,"t":"“Uzmite k srcu ove riječi: Sin Čovječji doista ima biti predan ljudima u ruke.”"},{"v":45,"t":"Ali oni nerazumješe te besjede, bijaše im skrivena te ne shvatiše, a bojahu se upitati ga o tome."},{"v":46,"t":"U njima se porodi misao tko bi od njih bio najveći."},{"v":47,"t":"Znajući tu misao njihova srca, uzme Isus dijete, postavi ga uza se"},{"v":48,"t":"i reče im: “Tko god primi ovo dijete u moje ime, mene prima. A tko mene prima, prima onoga koji me je poslao. Doista, tko je najmanji među vama svima, taj je velik!”"},{"v":49,"t":"Prihvati Ivan i reče: “Učitelju, vidjesmo jednoga koji u tvoje ime izgoni zloduhe. Mi smo mu branili, jer ne ide za nama.”"},{"v":50,"t":"Reče mu Isus: “Ne branite! Ta tko nije protiv vas, za vas je!”"},{"v":51,"t":"Kad su se navršili dani da bude uznesen, krenu Isus sa svom odlučnošću prema Jeruzalemu."},{"v":52,"t":"I posla glasnike pred sobom. Oni odoše i uđoše u neko samarijansko selo da mu priprave mjesto."},{"v":53,"t":"No ondje ga ne primiše jer je bio na putu u Jeruzalem."},{"v":54,"t":"Kada to vidješe učenici Jakov i Ivan, rekoše: “Gospodine, hoćeš li da kažemo neka oganj siđe s neba i uništi ih?”"},{"v":55,"t":"No on se okrenu i prekori ih."},{"v":56,"t":"I odoše u drugo selo."},{"v":57,"t":"Dok su išli putom, reče mu netko: “Za tobom ću kamo god ti pošao.”"},{"v":58,"t":"Reče mu Isus: “Lisice imaju jazbine, ptice nebeske gnijezda, a Sin Čovječji nema gdje bi glavu naslonio.”"},{"v":59,"t":"Drugomu nekom reče: “Pođi za mnom!” A on će mu: “Dopusti mi da prije odem i pokopam oca.”"},{"v":60,"t":"Reče mu: “Pusti neka mrtvi pokapaju svoje mrtve, a ti idi i navješćuj kraljevstvo Božje.”"},{"v":61,"t":"I neki drugi reče: “Za tobom ću, Gospodine, ali dopusti mi da se prije oprostim sa svojim ukućanima.”"},{"v":62,"t":"Reče mu Isus: “Nitko tko stavi ruku na plug pa se obazire natrag, nije prikladan za kraljevstvo Božje.”"}]},"10":{"fa":[{"v":1,"t":"و بعد از این امور، خداوند هفتاد نفر دیگر را نیز تعیین فرموده، ایشان را جفت جفت پیش روی خود به هر شهری و موضعی که خود عزیمت آن داشت، فرستاد."},{"v":2,"t":"پس بدیشان گفت: «حصاد بسیار است و عمله کم. پس ازصاحب حصاد درخواست کنید تا عمله ها برای حصاد خود بیرون نماید."},{"v":3,"t":"بروید، اینک من شما را چون بره‌ها در میان گرگان می‌فرستم."},{"v":4,"t":"وکیسه و توشه‌دان و کفشها با خود برمدارید وهیچ‌کس را در راه سلام منمایید،"},{"v":5,"t":"و در هرخانه‌ای که داخل شوید، اول گویید سلام بر این خانه باد."},{"v":6,"t":"پس هرگاه ابن السلام در آن خانه باشد، سلام شما بر آن قرار گیرد والا به سوی شما راجع شود."},{"v":7,"t":"و در آن خانه توقف نمایید و از آنچه دارند بخورید و بیاشامید، زیرا که مزدور مستحق اجرت خود است و از خانه به خانه نقل مکنید."},{"v":8,"t":"ودر هر شهری که رفتید و شما را پذیرفتند، از آنچه پیش شما گذارند بخورید."},{"v":9,"t":"و مریضان آنجا راشفا دهید و بدیشان گویید ملکوت خدا به شمانزدیک شده است."},{"v":10,"t":"لیکن در هر شهری که رفتیدو شما را قبول نکردند، به کوچه های آن شهربیرون شده بگویید،"},{"v":11,"t":"حتی خاکی که از شهرشما بر ما نشسته است، بر شما می‌افشانیم. لیکن این را بدانید که ملکوت خدا به شما نزدیک شده است."},{"v":12,"t":"و به شما می‌گویم که حالت سدوم در آن روز، از حالت آن شهر سهل تر خواهد بود."},{"v":13,"t":"وای بر تو‌ای خورزین؛ وای بر تو‌ای بیت صیدا، زیرا اگر معجزاتی که در شما ظاهر شددر صور و صیدون ظاهر می‌شد، هرآینه مدتی درپلاس و خاکستر نشسته، توبه می‌کردند."},{"v":14,"t":"لیکن حالت صور و صیدون در روز جزا، از حال شماآسانتر خواهد بود."},{"v":15,"t":"و تو‌ای کفرناحوم که سر به آسمان افراشته‌ای، تا به حهنم سرنگون خواهی شد."},{"v":16,"t":"آنکه شما را شنود، مرا شنیده و کسی‌که شما را حقیر شمارد مرا حقیر شمرده و هر‌که مراحقیر شمارد فرستنده مرا حقیر شمرده باشد.»"},{"v":17,"t":"پس آن هفتاد نفر با خرمی برگشته گفتند: «ای خداوند، دیوها هم به اسم تو اطاعت مامی کنند.»"},{"v":18,"t":"بدیشان گفت: «من شیطان را دیدم که چون برق از آسمان می‌افتد."},{"v":19,"t":"اینک شما راقوت می‌بخشم که ماران و عقربها و تمامی قوت دشمن را پایمال کنید و چیزی به شما ضرر هرگزنخواهد رسانید."},{"v":20,"t":"ولی از این شادی مکنید که ارواح اطاعت شما می‌کنند بلکه بیشتر شاد باشیدکه نامهای شما در آسمان مرقوم است.»"},{"v":21,"t":"در همان ساعت، عیسی در روح وجدنموده گفت: «ای پدر مالک آسمان و زمین، تو راسپاس می‌کنم که این امور را از دانایان وخردمندان مخفی داشتی و بر کودکان مکشوف ساختی. بلی‌ای پدر، چونکه همچنین منظور نظرتو افتاد.»"},{"v":22,"t":"و به سوی شاگردان خود توجه نموده گفت: «همه‌چیز را پدر به من سپرده است. وهیچ‌کس نمی شناسد که پسر کیست، جز پدر و نه که پدر کیست، غیر از پسر و هر‌که پسر بخواهدبرای او مکشوف سازد.»"},{"v":23,"t":"و در خلوت به شاگردان خود التفات فرموده گفت: «خوشابحال چشمانی که آنچه شما می‌بینید، می‌بینند."},{"v":24,"t":"زیرابه شما می‌گویم بسا انبیا و پادشاهان می‌خواستندآنچه شما می‌بینید، بنگرند و ندیدند و آنچه شمامی شنوید، بشنوند و نشنیدند.»"},{"v":25,"t":"ناگاه یکی از فقها برخاسته از روی امتحان به وی گفت: «ای استاد چه کنم تا وارث حیات جاودانی گردم؟»"},{"v":26,"t":"به وی گفت: «در تورات چه نوشته شده است و چگونه می‌خوانی؟»"},{"v":27,"t":"جواب داده، گفت: «اینکه خداوند خدای خود را به تمام دل و تمام نفس و تمام توانایی و تمام فکر خودمحبت نما و همسایه خود را مثل نفس خود.»"},{"v":28,"t":"گفت: «نیکو جواب گفتی. چنین بکن که خواهی زیست.»"},{"v":29,"t":"لیکن او چون خواست خودرا عادل نماید، به عیسی گفت: «و همسایه من کیست؟»"},{"v":30,"t":"عیسی در جواب وی گفت: «مردی که ازاورشلیم به سوی اریحا می‌رفت، به‌دستهای دزدان افتاد و او را برهنه کرده مجروح ساختند واو را نیم مرده واگذارده برفتند."},{"v":31,"t":"اتفاق کاهنی ازآن راه می‌آمد، چون او را بدید از کناره دیگررفت."},{"v":32,"t":"همچنین شخصی لاوی نیز از آنجا عبورکرده نزدیک آمد و بر او نگریسته از کناره دیگربرفت."},{"v":33,"t":"«لیکن شخصی سامری که مسافر بود نزدوی آمده چون او را بدید، دلش بر وی بسوخت."},{"v":34,"t":"پس پیش آمده بر زخمهای او روغن و شراب ریخته آنها را بست واو را بر مرکب خود سوارکرده به‌کاروانسرای رسانید و خدمت او کرد."},{"v":35,"t":"بامدادان چون روانه می‌شد، دو دینار درآورده به‌سرایدار داد و بدو گفت این شخص را متوجه باش و آنچه بیش از این خرج کنی، در حین مراجعت به تو دهم."},{"v":36,"t":"«پس به نظر تو کدام‌یک از این سه نفرهمسایه بود با آن شخص که به‌دست دزدان افتاد؟»"},{"v":37,"t":"گفت: «آنکه بر او رحمت کرد.» عیسی وی را گفت: «برو و تو نیز همچنان کن.»"},{"v":38,"t":"و هنگامی که می‌رفتند او وارد بلدی شد وزنی که مرتاه نام داشت، او را به خانه خودپذیرفت."},{"v":39,"t":"و او را خواهری مریم نام بود که نزدپایهای عیسی نشسته کلام او را می‌شنید."},{"v":40,"t":"امامرتاه بجهت زیادتی خدمت مضطرب می‌بود. پس نزدیک آمده، گفت: «ای خداوند آیا تو راباکی نیست که خواهرم مرا واگذارد که تنهاخدمت کنم، او را بفرما تا مرا یاری کند.»"},{"v":41,"t":"عیسی در جواب وی گفت: «ای مرتاه، ای مرتاه تو در چیزهای بسیار اندیشه و اضطراب داری."},{"v":42,"t":"لیکن یک چیز لازم است و مریم آن نصیب خوب را اختیار کرده است که از او گرفته نخواهد شد.»"}],"en":[{"v":1,"t":"Now after these things, the Lord also appointed seventy others, and sent them two by two ahead of him into every city and place where he was about to come."},{"v":2,"t":"Then he said to them, “The harvest is indeed plentiful, but the laborers are few. Pray therefore to the Lord of the harvest, that he may send out laborers into his harvest."},{"v":3,"t":"Go your ways. Behold, I send you out as lambs among wolves."},{"v":4,"t":"Carry no purse, nor wallet, nor sandals. Greet no one on the way."},{"v":5,"t":"Into whatever house you enter, first say, ‘Peace be to this house.’"},{"v":6,"t":"If a son of peace is there, your peace will rest on him; but if not, it will return to you."},{"v":7,"t":"Remain in that same house, eating and drinking the things they give, for the laborer is worthy of his wages. Don’t go from house to house."},{"v":8,"t":"Into whatever city you enter and they receive you, eat the things that are set before you."},{"v":9,"t":"Heal the sick who are there and tell them, ‘God’s Kingdom has come near to you.’"},{"v":10,"t":"But into whatever city you enter and they don’t receive you, go out into its streets and say,"},{"v":11,"t":"‘Even the dust from your city that clings to us, we wipe off against you. Nevertheless know this, that God’s Kingdom has come near to you.’"},{"v":12,"t":"I tell you, it will be more tolerable in that day for Sodom than for that city."},{"v":13,"t":"“Woe to you, Chorazin! Woe to you, Bethsaida! For if the mighty works had been done in Tyre and Sidon which were done in you, they would have repented long ago, sitting in sackcloth and ashes."},{"v":14,"t":"But it will be more tolerable for Tyre and Sidon in the judgment than for you."},{"v":15,"t":"You, Capernaum, who are exalted to heaven, will be brought down to Hades."},{"v":16,"t":"Whoever listens to you listens to me, and whoever rejects you rejects me. Whoever rejects me rejects him who sent me.”"},{"v":17,"t":"The seventy returned with joy, saying, “Lord, even the demons are subject to us in your name!”"},{"v":18,"t":"He said to them, “I saw Satan having fallen like lightning from heaven."},{"v":19,"t":"Behold, I give you authority to tread on serpents and scorpions, and over all the power of the enemy. Nothing will in any way hurt you."},{"v":20,"t":"Nevertheless, don’t rejoice in this, that the spirits are subject to you, but rejoice that your names are written in heaven.”"},{"v":21,"t":"In that same hour, Jesus rejoiced in the Holy Spirit, and said, “I thank you, O Father, Lord of heaven and earth, that you have hidden these things from the wise and understanding, and revealed them to little children. Yes, Father, for so it was well-pleasing in your sight.”"},{"v":22,"t":"Turning to the disciples, he said, “All things have been delivered to me by my Father. No one knows who the Son is, except the Father, and who the Father is, except the Son, and he to whomever the Son desires to reveal him.”"},{"v":23,"t":"Turning to the disciples, he said privately, “Blessed are the eyes which see the things that you see,"},{"v":24,"t":"for I tell you that many prophets and kings desired to see the things which you see, and didn’t see them, and to hear the things which you hear, and didn’t hear them.”"},{"v":25,"t":"Behold, a certain lawyer stood up and tested him, saying, “Teacher, what shall I do to inherit eternal life?”"},{"v":26,"t":"He said to him, “What is written in the law? How do you read it?”"},{"v":27,"t":"He answered, “You shall love the Lord your God with all your heart, with all your soul, with all your strength, and with all your mind; and your neighbor as yourself.”"},{"v":28,"t":"He said to him, “You have answered correctly. Do this, and you will live.”"},{"v":29,"t":"But he, desiring to justify himself, asked Jesus, “Who is my neighbor?”"},{"v":30,"t":"Jesus answered, “A certain man was going down from Jerusalem to Jericho, and he fell among robbers, who both stripped him and beat him, and departed, leaving him half dead."},{"v":31,"t":"By chance a certain priest was going down that way. When he saw him, he passed by on the other side."},{"v":32,"t":"In the same way a Levite also, when he came to the place and saw him, passed by on the other side."},{"v":33,"t":"But a certain Samaritan, as he traveled, came where he was. When he saw him, he was moved with compassion,"},{"v":34,"t":"came to him, and bound up his wounds, pouring on oil and wine. He set him on his own animal, brought him to an inn, and took care of him."},{"v":35,"t":"On the next day, when he departed, he took out two denarii, gave them to the host, and said to him, ‘Take care of him. Whatever you spend beyond that, I will repay you when I return.’"},{"v":36,"t":"Now which of these three do you think seemed to be a neighbor to him who fell among the robbers?”"},{"v":37,"t":"He said, “He who showed mercy on him.” Then Jesus said to him, “Go and do likewise.”"},{"v":38,"t":"As they went on their way, he entered into a certain village, and a certain woman named Martha received him into her house."},{"v":39,"t":"She had a sister called Mary, who also sat at Jesus’ feet and heard his word."},{"v":40,"t":"But Martha was distracted with much serving, and she came up to him, and said, “Lord, don’t you care that my sister left me to serve alone? Ask her therefore to help me.”"},{"v":41,"t":"Jesus answered her, “Martha, Martha, you are anxious and troubled about many things,"},{"v":42,"t":"but one thing is needed. Mary has chosen the good part, which will not be taken away from her.”"}],"hr":[{"v":1,"t":"Nakon toga odredi Gospodin drugih sedamdesetdvojicu učenika i posla ih po dva pred sobom u svaki grad i u svako mjesto kamo je kanio doći."},{"v":2,"t":"Govorio im je: “Žetva je velika, ali radnika malo. Molite dakle gospodara žetve da radnike pošalje u žetvu svoju."},{"v":3,"t":"Idite! Evo, šaljem vas kao janjce među vukove."},{"v":4,"t":"Ne nosite sa sobom ni kese, ni torbe, ni obuće. I nikoga putem ne pozdravljajte."},{"v":5,"t":"U koju god kuću uđete, najprije recite: 'Mir kući ovoj!'"},{"v":6,"t":"Bude li tko ondje prijatelj mira, počinut će na njemu mir vaš. Ako li ne, vratit će se na vas."},{"v":7,"t":"U toj kući ostanite, jedite i pijte što se kod njih nađe. Ta vrijedan je radnik plaće svoje. Ne prelazite iz kuće u kuću.”"},{"v":8,"t":"“Kad u koji grad uđete pa vas prime, jedite što vam se ponudi"},{"v":9,"t":"i liječite bolesnike koji su u njemu. I kazujte im: 'Približilo vam se kraljevstvo Božje!'"},{"v":10,"t":"A kad u neki grad uđete pa vas ne prime, iziđite na njegove ulice i recite:"},{"v":11,"t":"'I prašinu vašega grada, koja nam se nogu uhvatila, stresamo vam sa sebe! Ipak znajte ovo: Približilo se kraljevstvo Božje!'"},{"v":12,"t":"Kažem vam: Sodomcima će u onaj dan biti lakše negoli tomu gradu.”"},{"v":13,"t":"“Jao tebi, Korozaine! Jao tebi, Betsaido! Da su se u Tiru i Sidonu zbila čudesa koja su se dogodila u vama, odavna bi već, sjedeć u kostrijeti i pepelu, činili pokoru."},{"v":14,"t":"Ali Tiru i Sidonu bit će na Sudu lakše negoli vama."},{"v":15,"t":"I ti Kafarnaume! Zar ćeš se do neba uzvisiti? Do u Podzemlje ćeš se strovaliti."},{"v":16,"t":"Tko vas sluša, mene sluša; tko vas prezire, mene prezire. A tko mene prezire, prezire onoga koji mene posla.”"},{"v":17,"t":"Vratiše se zatim sedamdesetdvojica radosni govoreći: “Gospodine, i zlodusi nam se pokoravaju na tvoje ime!”"},{"v":18,"t":"A on im reče: “Promatrah Sotonu kako poput munje s neba pade."},{"v":19,"t":"Evo, dao sam vam vlast da gazite po zmijama i štipavcima i po svoj sili neprijateljevoj i ništa vam neće naškoditi."},{"v":20,"t":"Ali ne radujte se što vam se duhovi pokoravaju, nego radujte se što su vam imena zapisana na nebesima.”"},{"v":21,"t":"U taj isti čas uskliknu Isus u Duhu Svetom: “Slavim te, Oče, Gospodaru neba i zemlje, što si ovo sakrio od mudrih i umnih, a objavio malenima. Da, Oče! Tako se tebi svidjelo."},{"v":22,"t":"Sve mi preda Otac moj i nitko ne zna tko je Sin - doli Otac; niti tko je Otac - doli Sin i onaj kome Sin hoće da objavi.”"},{"v":23,"t":"Tada se okrene učenicima pa im nasamo reče: “Blago očima koje gledaju što vi gledate!"},{"v":24,"t":"Kažem vam: mnogi su proroci i kraljevi htjeli vidjeti što vi gledate, ali nisu vidjeli; i čuti što vi slušate, ali nisu čuli!”"},{"v":25,"t":"I gle, neki zakonoznanac usta i, da ga iskuša, upita: “Učitelju, što mi je činiti da život vječni baštinim?”"},{"v":26,"t":"A on mu reče: “U Zakonu što piše? Kako čitaš?”"},{"v":27,"t":"Odgovori mu onaj: Ljubi Gospodina Boga svojega iz svega srca svoga, i svom dušom svojom, i svom snagom svojom, i svim umom svojim; i svoga bližnjega kao sebe samoga!”"},{"v":28,"t":"Reče mu na to Isus: “Pravo si odgovorio. To čini i živjet ćeš.”"},{"v":29,"t":"Ali hoteći se opravdati, reče on Isusu: “A tko je moj bližnji?”"},{"v":30,"t":"Isus prihvati i reče: “Čovjek neki silazio iz Jeruzalema u Jerihon. Upao među razbojnike koji ga svukoše i izraniše pa odoše ostavivši ga polumrtva."},{"v":31,"t":"Slučajno je onim putem silazio neki svećenik, vidje ga i zaobiđe."},{"v":32,"t":"A tako i levit: prolazeći onuda, vidje ga i zaobiđe."},{"v":33,"t":"Neki Samarijanac putujući dođe do njega, vidje ga, sažali se"},{"v":34,"t":"pa mu pristupi i povije rane zalivši ih uljem i vinom. Zatim ga posadi na svoje živinče, odvede ga u gostinjac i pobrinu se za nj."},{"v":35,"t":"Sutradan izvadi dva denara, dade ih gostioničaru i reče: 'Pobrini se za njega. Ako što više potrošiš, isplatit ću ti kad se budem vraćao.'”"},{"v":36,"t":"“Što ti se čini, koji je od ove trojice bio bližnji onomu koji je upao među razbojnike?”"},{"v":37,"t":"On odgovori: “Onaj koji mu iskaza milosrđe.” Nato mu reče Isus: “Idi pa i ti čini tako!”"},{"v":38,"t":"Dok su oni tako putovali, uđe on u jedno selo. Žena neka, imenom Marta, primi ga u kuću."},{"v":39,"t":"Imala je sestru koja se zvala Marija. Ona sjede do nogu Gospodinovih i slušaše riječ njegovu."},{"v":40,"t":"A Marta bijaše sva zauzeta posluživanjem pa pristupi i reče: “Gospodine, zar ne mariš što me sestra samu ostavila posluživati? Reci joj dakle da mi pomogne.”"},{"v":41,"t":"Odgovori joj Gospodin: “Marta, Marta! Brineš se i uznemiruješ za mnogo,"},{"v":42,"t":"a jedno je potrebno. Marija je uistinu izabrala bolji dio, koji joj se neće oduzeti.”"}]},"11":{"fa":[{"v":1,"t":"و هنگامی که او در موضعی دعا می‌کردچون فارغ شد، یکی از شاگردانش به وی گفت: «خداوندا دعا کردن را به ما تعلیم نما، چنانکه یحیی شاگردان خود را بیاموخت.»"},{"v":2,"t":"بدیشان گفت: «هرگاه دعا کنید گویید‌ای پدرما که در آسمانی، نام تو مقدس باد. ملکوت توبیاید. اراده تو چنانکه در آسمان است در زمین نیزکرده شود."},{"v":3,"t":"نان کفاف ما را روز به روز به ما بده."},{"v":4,"t":"و گناهان ما را ببخش زیرا که ما نیز هر قرضدار خود را می‌بخشیم. و ما را در آزمایش میاور، بلکه ما را از شریر رهایی ده.»"},{"v":5,"t":"و بدیشان گفت: «کیست از شما که دوستی داشته باشد و نصف شب نزد وی آمده بگوید‌ای دوست سه قرص نان به من قرض ده،"},{"v":6,"t":"چونکه یکی از دوستان من از سفر بر من وارد شده وچیزی ندارم که پیش او گذارم."},{"v":7,"t":"پس او از اندرون در جواب گوید مرا زحمت مده، زیرا که الان دربسته است و بچه های من در رختخواب با من خفته‌اند نمی توانم برخاست تا به تو دهم."},{"v":8,"t":"به شمامی گویم هر‌چند به علت دوستی برنخیزد تا بدودهد، لیکن بجهت لجاجت خواهد برخاست و هرآنچه حاجت دارد، بدو خواهد داد."},{"v":9,"t":"«و من به شما می‌گویم سوال کنید که به شماداده خواهد شد. بطلبید که خواهید یافت. بکوبیدکه برای شما بازکرده خواهد شد."},{"v":10,"t":"زیرا هر‌که سوال کند، یابد و هر‌که بطلبد، خواهد یافت وهرکه کوبد، برای او باز کرده خواهد شد."},{"v":11,"t":"وکیست از شما که پدر باشد و پسرش از او نان خواهد، سنگی بدو دهد یا اگر ماهی خواهد، به عوض ماهی ماری بدو بخشد،"},{"v":12,"t":"یا اگرتخم‌مرغی بخواهد، عقربی بدو عطا کند."},{"v":13,"t":"پس اگر شما با آنکه شریر هستید می‌دانید چیزهای نیکو را به اولاد خود باید داد، چند مرتبه زیادترپدر آسمانی شما روح‌القدس را خواهد داد به هرکه از او سوال کند.»"},{"v":14,"t":"و دیوی را که گنگ بود بیرون می‌کرد وچون دیو بیرون شد، گنگ گویا گردید و مردم تعجب نمودند."},{"v":15,"t":"لیکن بعضی از ایشان گفتند که «دیوها را به یاری بعلزبول رئیس دیوها بیرون می‌کند.»"},{"v":16,"t":"و دیگران از روی امتحان آیتی آسمانی از او طلب نمودند."},{"v":17,"t":"پس او خیالات ایشان را درک کرده بدیشان گفت: «هر مملکتی که برخلاف خود منقسم شود، تباه گردد و خانه‌ای که بر خانه منقسم شود، منهدم گردد."},{"v":18,"t":"پس شیطان نیز اگر به ضد خود منقسم شود سلطنت اوچگونه پایدار بماند. زیرا می‌گویید که من به اعانت بعلزبول دیوها را بیرون می‌کنم."},{"v":19,"t":"پس اگرمن دیوها را به وساطت بعلزبول بیرون می‌کنم، پسران شما به وساطت که آنها را بیرون می‌کنند؟ از اینجهت ایشان داوران بر شما خواهند بود."},{"v":20,"t":"لیکن هرگاه به انگشت خدا دیوها را بیرون می‌کنم، هرآینه ملکوت خدا ناگهان بر شما آمده است."},{"v":21,"t":"وقتی که مرد زورآور سلاح پوشیده خانه خود را نگاه دارد، اموال او محفوظ می‌باشد."},{"v":22,"t":"اما چون شخصی زورآورتر از او آید بر او غلبه یافته همه اسلحه او را که بدان اعتماد می‌داشت، از او می‌گیرد و اموال او را تقسیم می‌کند."},{"v":23,"t":"کسی‌که با من نیست، برخلاف من است و آنکه با من جمع نمی کند، پراکنده می‌سازد."},{"v":24,"t":"چون روح پلید از انسان بیرون آید به مکانهای بی‌آب بطلب آرامی گردش می‌کند وچون نیافت می‌گوید به خانه خود که از آن بیرون آمدم برمی گردم."},{"v":25,"t":"پس چون آید، آن را جاروب کرده شده و آراسته می‌بیند."},{"v":26,"t":"آنگاه می‌رود وهفت روح دیگر، شریرتر از خود برداشته داخل شده در آنجا ساکن می‌گردد و اواخر آن شخص ازاوائلش بدتر می‌شود.»"},{"v":27,"t":"چون او این سخنان را می‌گفت، زنی از آن میان به آواز بلند وی را گفت «خوشابحال آن رحمی که تو را حمل کرد و پستانهایی که مکیدی.»"},{"v":28,"t":"لیکن او گفت: «بلکه خوشابحال آنانی که کلام خدا را می‌شنوند و آن را حفظمی کنند.»"},{"v":29,"t":"و هنگامی که مردم بر او ازدحام می‌نمودند، سخن‌گفتن آغاز کرد که «اینان فرقه‌ای شریرند که آیتی طلب می‌کنند و آیتی بدیشان عطا نخواهدشد، جز آیت یونس نبی."},{"v":30,"t":"زیرا چنانکه یونس برای اهل نینوا آیت شد، همچنین پسر انسان نیزبرای این فرقه خواهد بود."},{"v":31,"t":"ملکه جنوب در روزداوری با مردم این فرقه برخاسته، بر ایشان حکم خواهد کرد زیرا که از اقصای زمین آمد تا حکمت سلیمان را بشنود و اینک در اینجا کسی بزرگتر ازسلیمان است."},{"v":32,"t":"مردم نینوا در روز داوری با این طبقه برخاسته بر ایشان حکم خواهند کرد زیرا که به موعظه یونس توبه کردند و اینک در اینجا کسی بزرگتر از یونس است."},{"v":33,"t":"و هیچ‌کس چراغی نمی افروزد تا آن را درپنهانی یا زیر پیمانه‌ای بگذارد، بلکه بر چراغدان، تا هر‌که داخل شود روشنی را بیند."},{"v":34,"t":"چراغ بدن چشم است، پس مادامی که چشم تو بسیط است تمامی جسدت نیز روشن است و لیکن اگر فاسدباشد، جسد تو نیز تاریک بود."},{"v":35,"t":"پس باحذر باش مبادا نوری که در تو است، ظلمت باشد."},{"v":36,"t":"بنابراین هرگاه تمامی جسم تو روشن باشد وذره‌ای ظلمت نداشته باشد همه‌اش روشن خواهد بود، مثل وقتی که چراغ به تابش خود، تورا روشنایی می‌دهد.»"},{"v":37,"t":"و هنگامی که سخن می‌گفت یکی ازفریسیان از او وعده خواست که در خانه اوچاشت بخورد. پس داخل شده بنشست."},{"v":38,"t":"امافریسی چون دید که پیش از چاشت دست نشست، تعجب نمود."},{"v":39,"t":"خداوند وی را گفت: «همانا شما‌ای فریسیان بیرون پیاله و بشقاب راطاهر می‌سازید ولی درون شما پر از حرص وخباثت است."},{"v":40,"t":"‌ای احمقان آیا او که بیرون راآفرید، اندرون را نیز نیافرید؟"},{"v":41,"t":"بلکه از آنچه دارید، صدقه دهید که اینک همه‌چیز برای شماطاهر خواهد گشت."},{"v":42,"t":"وای بر شما‌ای فریسیان که ده‌یک از نعناع و سداب و هر قسم سبزی رامی دهید و از دادرسی و محبت خدا تجاوزمی نمایید، اینها را می‌باید به‌جا آورید و آنها رانیز ترک نکنید."},{"v":43,"t":"وای بر شما‌ای فریسیان که صدر کنایس و سلام در بازارها را دوست می‌دارید."},{"v":44,"t":"وای بر شما‌ای کاتبان و فریسیان ریاکار زیرا که مانند قبرهای پنهان شده هستید که مردم بر آنها راه می‌روند و نمی دانند.»"},{"v":45,"t":"آنگاه یکی از فقها جواب داده گفت: «ای معلم، بدین سخنان ما را نیز سرزنش می‌کنی؟»"},{"v":46,"t":"گفت «وای بر شما نیز‌ای فقها زیرا که بارهای گران را بر مردم می‌نهید و خود بر آن بارها، یک انگشت خود را نمی گذارید."},{"v":47,"t":"وای بر شما زیراکه مقابر انبیا را بنا می‌کنید و پدران شما ایشان راکشتند."},{"v":48,"t":"پس به‌کارهای پدران خود شهادت می‌دهید و از آنها راضی هستید، زیرا آنها ایشان را کشتند و شما قبرهای ایشان را می‌سازید."},{"v":49,"t":"ازاین‌رو حکمت خدا نیز فرموده است که به سوی ایشان انبیا و رسولان می‌فرستم و بعضی از ایشان را خواهند کشت و بر بعضی جفا کرد،"},{"v":50,"t":"تا انتقام خون جمیع انبیا که از بنای عالم ریخته شد از این طبقه گرفته شود."},{"v":51,"t":"از خون هابیل تا خون زکریاکه در میان مذبح و هیکل کشته شد. بلی به شمامی گویم که از این فرقه بازخواست خواهد شد."},{"v":52,"t":"وای بر شما‌ای فقها، زیرا کلید معرفت رابرداشته‌اید که خود داخل نمی شوید و داخل‌شوندگان را هم مانع می‌شوید.»"},{"v":53,"t":"و چون او این سخنان را بدیشان می‌گفت، کاتبان و فریسیان با او بشدت درآویختند و درمطالب بسیار سوالها از او می‌کردند."},{"v":54,"t":"و در کمین او می‌بودند تا نکته‌ای از زبان او گرفته مدعی اوبشوند."}],"en":[{"v":1,"t":"When he finished praying in a certain place, one of his disciples said to him, “Lord, teach us to pray, just as John also taught his disciples.”"},{"v":2,"t":"He said to them, “When you pray, say, ‘Our Father in heaven, may your name be kept holy. May your Kingdom come. May your will be done on earth, as it is in heaven."},{"v":3,"t":"Give us day by day our daily bread."},{"v":4,"t":"Forgive us our sins, for we ourselves also forgive everyone who is indebted to us. Bring us not into temptation, but deliver us from the evil one.’”"},{"v":5,"t":"He said to them, “Which of you, if you go to a friend at midnight and tell him, ‘Friend, lend me three loaves of bread,"},{"v":6,"t":"for a friend of mine has come to me from a journey, and I have nothing to set before him,’"},{"v":7,"t":"and he from within will answer and say, ‘Don’t bother me. The door is now shut, and my children are with me in bed. I can’t get up and give it to you’?"},{"v":8,"t":"I tell you, although he will not rise and give it to him because he is his friend, yet because of his persistence, he will get up and give him as many as he needs."},{"v":9,"t":"“I tell you, keep asking, and it will be given you. Keep seeking, and you will find. Keep knocking, and it will be opened to you."},{"v":10,"t":"For everyone who asks receives. He who seeks finds. To him who knocks it will be opened."},{"v":11,"t":"“Which of you fathers, if your son asks for bread, will give him a stone? Or if he asks for a fish, he won’t give him a snake instead of a fish, will he?"},{"v":12,"t":"Or if he asks for an egg, he won’t give him a scorpion, will he?"},{"v":13,"t":"If you then, being evil, know how to give good gifts to your children, how much more will your heavenly Father give the Holy Spirit to those who ask him?”"},{"v":14,"t":"He was casting out a demon, and it was mute. When the demon had gone out, the mute man spoke; and the multitudes marveled."},{"v":15,"t":"But some of them said, “He casts out demons by Beelzebul, the prince of the demons.”"},{"v":16,"t":"Others, testing him, sought from him a sign from heaven."},{"v":17,"t":"But he, knowing their thoughts, said to them, “Every kingdom divided against itself is brought to desolation. A house divided against itself falls."},{"v":18,"t":"If Satan also is divided against himself, how will his kingdom stand? For you say that I cast out demons by Beelzebul."},{"v":19,"t":"But if I cast out demons by Beelzebul, by whom do your children cast them out? Therefore they will be your judges."},{"v":20,"t":"But if I by God’s finger cast out demons, then God’s Kingdom has come to you."},{"v":21,"t":"“When the strong man, fully armed, guards his own dwelling, his goods are safe."},{"v":22,"t":"But when someone stronger attacks him and overcomes him, he takes from him his whole armor in which he trusted, and divides his plunder."},{"v":23,"t":"“He who is not with me is against me. He who doesn’t gather with me scatters."},{"v":24,"t":"The unclean spirit, when he has gone out of the man, passes through dry places, seeking rest; and finding none, he says, ‘I will turn back to my house from which I came out.’"},{"v":25,"t":"When he returns, he finds it swept and put in order."},{"v":26,"t":"Then he goes and takes seven other spirits more evil than himself, and they enter in and dwell there. The last state of that man becomes worse than the first.”"},{"v":27,"t":"It came to pass, as he said these things, a certain woman out of the multitude lifted up her voice and said to him, “Blessed is the womb that bore you, and the breasts which nursed you!”"},{"v":28,"t":"But he said, “On the contrary, blessed are those who hear the word of God, and keep it.”"},{"v":29,"t":"When the multitudes were gathering together to him, he began to say, “This is an evil generation. It seeks after a sign. No sign will be given to it but the sign of Jonah the prophet."},{"v":30,"t":"For even as Jonah became a sign to the Ninevites, so the Son of Man will also be to this generation."},{"v":31,"t":"The Queen of the South will rise up in the judgment with the men of this generation and will condemn them, for she came from the ends of the earth to hear the wisdom of Solomon; and behold, one greater than Solomon is here."},{"v":32,"t":"The men of Nineveh will stand up in the judgment with this generation, and will condemn it, for they repented at the preaching of Jonah; and behold, one greater than Jonah is here."},{"v":33,"t":"“No one, when he has lit a lamp, puts it in a cellar or under a basket, but on a stand, that those who come in may see the light."},{"v":34,"t":"The lamp of the body is the eye. Therefore when your eye is good, your whole body is also full of light; but when it is evil, your body also is full of darkness."},{"v":35,"t":"Therefore see whether the light that is in you isn’t darkness."},{"v":36,"t":"If therefore your whole body is full of light, having no part dark, it will be wholly full of light, as when the lamp with its bright shining gives you light.”"},{"v":37,"t":"Now as he spoke, a certain Pharisee asked him to dine with him. He went in and sat at the table."},{"v":38,"t":"When the Pharisee saw it, he marveled that he had not first washed himself before dinner."},{"v":39,"t":"The Lord said to him, “Now you Pharisees cleanse the outside of the cup and of the platter, but your inward part is full of extortion and wickedness."},{"v":40,"t":"You foolish ones, didn’t he who made the outside make the inside also?"},{"v":41,"t":"But give for gifts to the needy those things which are within, and behold, all things will be clean to you."},{"v":42,"t":"But woe to you Pharisees! For you tithe mint and rue and every herb, but you bypass justice and God’s love. You ought to have done these, and not to have left the other undone."},{"v":43,"t":"Woe to you Pharisees! For you love the best seats in the synagogues and the greetings in the marketplaces."},{"v":44,"t":"Woe to you, scribes and Pharisees, hypocrites! For you are like hidden graves, and the men who walk over them don’t know it.”"},{"v":45,"t":"One of the lawyers answered him, “Teacher, in saying this you insult us also.”"},{"v":46,"t":"He said, “Woe to you lawyers also! For you load men with burdens that are difficult to carry, and you yourselves won’t even lift one finger to help carry those burdens."},{"v":47,"t":"Woe to you! For you build the tombs of the prophets, and your fathers killed them."},{"v":48,"t":"So you testify and consent to the works of your fathers. For they killed them, and you build their tombs."},{"v":49,"t":"Therefore also the wisdom of God said, ‘I will send to them prophets and apostles; and some of them they will kill and persecute,"},{"v":50,"t":"that the blood of all the prophets, which was shed from the foundation of the world, may be required of this generation,"},{"v":51,"t":"from the blood of Abel to the blood of Zachariah, who perished between the altar and the sanctuary.’ Yes, I tell you, it will be required of this generation."},{"v":52,"t":"Woe to you lawyers! For you took away the key of knowledge. You didn’t enter in yourselves, and those who were entering in, you hindered.”"},{"v":53,"t":"As he said these things to them, the scribes and the Pharisees began to be terribly angry, and to draw many things out of him,"},{"v":54,"t":"lying in wait for him, and seeking to catch him in something he might say, that they might accuse him."}],"hr":[{"v":1,"t":"Jednom je Isus na nekome mjestu molio. Čim presta, reče mu jedan od učenika: “Gospodine, nauči nas moliti kao što je i Ivan naučio svoje učenike.”"},{"v":2,"t":"On im reče: “Kad molite, govorite: 'Oče! Sveti se ime tvoje! Dođi kraljevstvo tvoje!"},{"v":3,"t":"Kruh naš svagdanji daji nam svaki dan!"},{"v":4,"t":"I otpusti nam grijehe naše: ta i mi otpuštamo svakom dužniku svojem! I ne uvedi nas u napast!'”"},{"v":5,"t":"I reče im: “Tko to od vas ima ovakva prijatelja? Pođe k njemu o ponoći i rekne mu: 'Prijatelju, posudi mi tri kruha."},{"v":6,"t":"Prijatelj mi se s puta svratio te nemam što staviti preda nj!'"},{"v":7,"t":"A onaj mu iznutra odgovori: 'Ne dosađuj mi! Vrata su već zatvorena, a dječica sa mnom u postelji. Ne mogu ustati da ti dadnem...'"},{"v":8,"t":"Kažem vam: ako i ne ustane da mu dadne zato što mu je prijatelj, ustat će i dati mu što god treba zbog njegove bezočnosti.”"},{"v":9,"t":"“I ja vama kažem: Ištite i dat će vam se! Tražite i naći ćete! Kucajte i otvorit će vam se!"},{"v":10,"t":"Doista, tko god ište, prima; i tko traži, nalazi; i onomu tko kuca, otvorit će se.”"},{"v":11,"t":"“A koji je to otac među vama: kad ga sin zaište ribu, zar će mu mjesto ribe zmiju dati?"},{"v":12,"t":"Ili kad zaište jaje, zar će mu dati štipavca?"},{"v":13,"t":"Ako dakle vi, iako zli, znate dobrim darima darivati djecu svoju, koliko li će više Otac s neba obdariti Duhom Svetim one koji ga zaištu!”"},{"v":14,"t":"I istjerivaše đavla koji bijaše nijem. Kad iziđe đavao, progovori njemak. I mnoštvo se divilo."},{"v":15,"t":"A neki od njih rekoše: “Po Beelzebulu, poglavici đavolskom, izgoni đavle!”"},{"v":16,"t":"A drugi su iskušavajući ga, tražili od njega kakav znak s neba."},{"v":17,"t":"Ali on, znajući njihove misli, reče im: “Svako kraljevstvo u sebi razdijeljeno opustjet će i kuća će na kuću pasti."},{"v":18,"t":"Ako je dakle Sotona u sebi razdijeljen, kako će opstati kraljevstvo njegovo? Jer vi kažete da ja po Beelzebulu izgonim đavle."},{"v":19,"t":"Ako dakle ja po Beelzebulu izgonim đavle, po kome ih vaši sinovi izgone? Zato će vam oni biti suci."},{"v":20,"t":"Ali ako ja prstom Božjim izgonim đavle, zbilja je došlo k vama kraljevstvo Božje.”"},{"v":21,"t":"“Dokle god jaki i naoružani čuva svoj stan, u miru je sav njegov posjed."},{"v":22,"t":"Ali ako dođe jači od njega, svlada ga i otme mu sve njegovo oružje u koje se uzdao, a plijen razdijeli.”"},{"v":23,"t":"“Tko nije sa mnom, protiv mene je. I tko sa mnom ne sabire, rasipa.”"},{"v":24,"t":"“Kad nečisti duh iziđe iz čovjeka, luta bezvodnim mjestima tražeći spokoja. Kad ga ne nađe, rekne: 'Vratit ću se u kuću odakle iziđoh.'"},{"v":25,"t":"Došavši, nađe je pometenu i uređenu."},{"v":26,"t":"Tada ode i uzme sa sobom sedam drugih duhova, gorih od sebe, te uđu i nastane se ondje. Na kraju bude onomu čovjeku gore nego na početku.”"},{"v":27,"t":"Dok je on to govorio, povika neka žena iz mnoštva: “Blažena utroba koja te nosila i prsi koje si sisao!”"},{"v":28,"t":"On odgovori: “Još blaženiji oni koji slušaju riječ Božju i čuvaju je!”"},{"v":29,"t":"Kad je nagrnulo mnoštvo, poče im Isus govoriti: “Naraštaj ovaj naraštaj je opak. Znak traži, ali mu se znak neće dati doli znak Jonin."},{"v":30,"t":"Doista, kao što je Jona bio znak Ninivljanima, tako će biti i Sin Čovječji ovomu naraštaju.”"},{"v":31,"t":"“Kraljica će Juga ustati na Sudu s ljudima ovog naraštaja i osuditi ih jer je s krajeva zemlje došla čuti mudrost Salomonovu, a evo ovdje i više od Salomona!"},{"v":32,"t":"Ninivljani će ustati na Sudu s ovim naraštajem i osuditi ga jer se obratiše na propovijed Joninu, a evo ovdje i više od Jone!”"},{"v":33,"t":"“Nitko ne užiže svjetiljku da je stavi u zakutak ili pod posudu, nego na svijećnjak da oni koji ulaze vide svjetlost."},{"v":34,"t":"Oko je svjetiljka tvomu tijelu. Kad ti je oko bistro, sve ti je tijelo svijetlo. A kad je ono nevaljalo, i tijelo ti je tamno."},{"v":35,"t":"Pazi dakle da svjetlost koja je u tebi ne bude tamna."},{"v":36,"t":"Ako ti dakle sve tijelo bude svijetlo, bez djelića tame, bit će posve svijetlo, kao kad te svjetiljka svojim sjajem rasvjetljuje.”"},{"v":37,"t":"Dok je on govorio, pozva ga neki farizej k sebi na objed. On uđe i priđe k stolu."},{"v":38,"t":"Vidjevši to, farizej se začudi što se Isus prije objeda ne opra."},{"v":39,"t":"A Gospodin mu reče: “Da, vi farizeji čistite vanjštinu čaše u zdjele, a nutrina vam je puna grabeža i pakosti."},{"v":40,"t":"Bezumnici! Nije li onaj koji načini vanjštinu načinio i nutrinu."},{"v":41,"t":"Nego, dajte za milostinju ono iznutra i gle - sve vam je čisto.”"},{"v":42,"t":"“Ali jao vama, farizeji! Namirujete desetinu od metvice i rutvice i svake vrste povrća, a ne marite za pravednost i ljubav Božju. Ovo je trebalo činiti, a ono ne zanemariti.”"},{"v":43,"t":"“Jao vama farizeji! Volite prvo sjedalo u sinagogama i pozdrave na trgovima."},{"v":44,"t":"Jao vama! Vi ste kao nezamjetljivi grobovi po kojima ljudi ne znajući hode.”"},{"v":45,"t":"Nato će neki zakonoznanac: “Učitelju, tako govoreći i nas vrijeđaš.”"},{"v":46,"t":"A on reče: “Jao i vama, zakonoznanci! Tovarite na ljude terete nepodnosive, a sami ni da ih se jednim prstom dotaknete.”"},{"v":47,"t":"“Jao vama! Podižete spomenike prorocima, a vaši ih oci ubiše."},{"v":48,"t":"Zato ste svjedoci i sumišljenici djela svojih otaca: oni ih ubiše, a vi spomenike podižete!"},{"v":49,"t":"Zbog toga i kaza Mudrost Božja: 'Poslat ću k njima proroke i apostole. Neke će poubijati i prognati -"},{"v":50,"t":"da se od ovog naraštaja zatraži krv svih proroka prolivena od postanka svijeta,"},{"v":51,"t":"od krvi Abelove do krvi Zaharije, koji je pogubljen između žrtvenika i svetišta.' Da, kažem vam, tražit će se od ovoga naraštaja!”"},{"v":52,"t":"“Jao vama, zakonoznanci! Uzeste ključ znanja: sami ne uđoste, a spriječiste one koji htjedoše ući.”"},{"v":53,"t":"Kad Isus izađe odande, stadoše pismoznanci i farizeji žestoko na nj navaljivati i postavljati mu mnoga pitanja"},{"v":54,"t":"vrebajući na nj, ne bi li štogod ulovili iz njegovih usta."}]},"12":{"fa":[{"v":1,"t":"و در آن میان، وقتی که هزاران از خلق جمع شدند، به نوعی که یکدیگر راپایمال می‌کردند، به شاگردان خود به سخن‌گفتن شروع کرد. «اول آنکه از خمیرمایه فریسیان که ریاکاری است احتیاط کنید."},{"v":2,"t":"زیرا چیزی نهفته نیست که آشکار نشود و نه مستوری که معلوم نگردد."},{"v":3,"t":"بنابراین آنچه در تاریکی گفته‌اید، درروشنایی شنیده خواهد شد و آنچه در خلوتخانه در گوش گفته‌اید بر پشت بامها ندا شود."},{"v":4,"t":"لیکن‌ای دوستان من، به شما می‌گویم از قاتلان جسم که قدرت ندارند بیشتر از این بکنند، ترسان مباشید."},{"v":5,"t":"بلکه به شما نشان می‌دهم که از که باید ترسید، از او بترسید که بعد از کشتن، قدرت دارد که به جهنم بیفکند. بلی به شما می‌گویم از او بترسید."},{"v":6,"t":"آیا پنج گنجشک به دو فلس فروخته نمی شود وحال آنکه یکی از آنها نزد خدا فراموش نمی شود؟"},{"v":7,"t":"بلکه مویهای سر شما همه شمرده شده است. پس بیم مکنید، زیرا که از چندان گنجشک بهتر هستید."},{"v":8,"t":"«لیکن به شما می‌گویم هر‌که نزد مردم به من اقرار کند، پسر انسان نیز پیش فرشتگان خدا او رااقرار خواهد کرد."},{"v":9,"t":"اما هر‌که مرا پیش مردم انکارکند، نزد فرشتگان خدا انکار کرده خواهد شد."},{"v":10,"t":"و هر‌که سخنی برخلاف پسر انسان گوید، آمرزیده شود. اما هر‌که به روح‌القدس کفر گویدآمرزیده نخواهد شد."},{"v":11,"t":"و چون شما را درکنایس و به نزد حکام و دیوانیان برند، اندیشه مکنید که چگونه و به چه نوع حجت آورید یا چه بگویید."},{"v":12,"t":"زیرا که در همان ساعت روح‌القدس شما را خواهد آموخت که چه باید گفت.»"},{"v":13,"t":"و شخصی از آن جماعت به وی گفت: «ای استاد، برادر مرا بفرما تا ارث پدر را با من تقسیم کند.»"},{"v":14,"t":"به وی گفت: «ای مرد که مرا بر شما داوریا مقسم قرار داده است؟»"},{"v":15,"t":"پس بدیشان گفت: «زنهار از طمع بپرهیزید زیرا اگرچه اموال کسی زیاد شود، حیات او از اموالش نیست.»"},{"v":16,"t":"و مثلی برای ایشان آورده، گفت: «شخصی دولتمند را از املاکش محصول وافر پیدا شد."},{"v":17,"t":"پس با خود اندیشیده، گفت چه کنم؟ زیراجایی که محصول خود را انبار کنم، ندارم."},{"v":18,"t":"پس گفت چنین می‌کنم انبارهای خود را خراب کرده، بزرگتر بنا می‌کنم و در آن تمامی حاصل و اموال خود را جمع خواهم کرد."},{"v":19,"t":"و نفس خود راخواهم گفت که‌ای جان اموال فراوان اندوخته شده بجهت چندین سال داری. الحال بیارام و به اکل و شرب و شادی بپرداز."},{"v":20,"t":"خدا وی را گفت‌ای احمق در همین شب جان تو را از تو خواهندگرفت، آنگاه آنچه اندوخته‌ای، از آن که خواهدبود؟"},{"v":21,"t":"همچنین است هر کسی‌که برای خودذخیره کند و برای خدا دولتمند نباشد.»"},{"v":22,"t":"پس به شاگردان خود گفت: «از این جهت به شما می‌گویم که اندیشه مکنید بجهت جان خودکه چه بخورید و نه برای بدن که چه بپوشید."},{"v":23,"t":"جان از خوراک و بدن از پوشاک بهتر است."},{"v":24,"t":"کلاغان را ملاحظه کنید که نه زراعت می‌کنندو نه حصاد و نه گنجی و نه انباری دارند و خدا آنهارا می‌پروراند. آیا شما به چند مرتبه از مرغان بهترنیستید؟"},{"v":25,"t":"و کیست از شما که به فکر بتواندذراعی بر قامت خود افزاید."},{"v":26,"t":"پس هرگاه توانایی کوچکترین کاری را ندارید چرا برای مابقی می اندیشید."},{"v":27,"t":"سوسنهای چمن را بنگریدچگونه نمو می‌کنند و حال آنکه نه زحمت می‌کشند و نه می‌ریسند، اما به شما می‌گویم که سلیمان با همه جلالش مثل یکی از اینها پوشیده نبود."},{"v":28,"t":"پس هرگاه خدا علفی را که امروز درصحرا است و فردا در تنور افکنده می‌شود چنین می‌پوشاند، چقدر بیشتر شما را‌ای سست‌ایمانان."},{"v":29,"t":"پس شما طالب مباشید که چه بخوریدیا چه بیاشامید و مضطرب مشوید."},{"v":30,"t":"زیرا که امت های جهان، همه این چیزها را می‌طلبند، لیکن پدر شما می‌داند که به این چیزها احتیاج دارید."},{"v":31,"t":"بلکه ملکوت خدا را طلب کنید که جمیع این چیزها برای شما افزوده خواهد شد."},{"v":32,"t":"ترسان مباشید‌ای گله کوچک، زیرا که مرضی پدر شما است که ملکوت را به شما عطافرماید."},{"v":33,"t":"آنچه دارید بفروشید و صدقه دهید وکیسه‌ها بسازید که کهنه نشود و گنجی را که تلف نشود، در آسمان جایی که دزد نزدیک نیاید و بیدتباه نسازد."},{"v":34,"t":"زیرا جایی که خزانه شما است، دل شما نیز در آنجا می‌باشد."},{"v":35,"t":"کمرهای خود را بسته چراغهای خود راافروخته بدارید."},{"v":36,"t":"و شما مانند کسانی باشید که انتظار آقای خود را می‌کشند که چه وقت ازعروسی مراجعت کند تا هروقت آید و در رابکوبد، بی‌درنگ برای او بازکنند."},{"v":37,"t":"خوشابحال آن غلامان که آقای ایشان چون آید ایشان را بیداریابد. هر آینه به شما می‌گویم که کمر خود را بسته ایشان را خواهد نشانید و پیش آمده، ایشان راخدمت خواهد کرد."},{"v":38,"t":"و اگر در پاس دوم یا سوم از شب بیاید و ایشان را چنین یابد، خوشا بحال آن غلامان."},{"v":39,"t":"اما این را بدانید که اگر صاحب‌خانه می‌دانست که دزد در چه ساعت می‌آید، بیدارمی ماند و نمی گذاشت که به خانه‌اش نقب زنند."},{"v":40,"t":"پس شما نیز مستعد باشید، زیرا در ساعتی که گمان نمی برید پسر انسان می‌آید.»"},{"v":41,"t":"پطرس به وی گفت: «ای خداوند، آیا این مثل را برای ما زدی یا بجهت همه.»"},{"v":42,"t":"خداوندگفت: «پس کیست آن ناظر امین و دانا که مولای اووی را بر سایر خدام خود گماشته باشد تا آذوقه را در وقتش به ایشان تقسیم کند."},{"v":43,"t":"خوشابحال آن غلام که آقایش چون آید، او را در چنین کارمشغول یابد."},{"v":44,"t":"هرآینه به شما می‌گویم که او رابر همه مایملک خود خواهد گماشت."},{"v":45,"t":"لیکن اگر آن غلام در خاطر خود گوید، آمدن آقایم به طول می‌انجامد و به زدن غلامان و کنیزان و به خوردن و نوشیدن و میگساریدن شروع کند،"},{"v":46,"t":"هرآینه مولای آن غلام آید، در روزی که منتظر او نباشد و در ساعتی که او نداند و او را دوپاره کرده نصیبش را با خیانتکاران قرار دهد."},{"v":47,"t":"«اما آن غلامی که اراده مولای خویش رادانست و خود را مهیا نساخت تا به اراده او عمل نماید، تازیانه بسیار خواهد خورد."},{"v":48,"t":"اما آنکه نادانسته کارهای شایسته ضرب کند، تازیانه کم خواهد خورد. و به هر کسی‌که عطا زیاده شود ازوی مطالبه زیادتر گردد و نزد هر‌که امانت بیشترنهند از او بازخواست زیادتر خواهند کرد."},{"v":49,"t":"من آمدم تا آتشی در زمین افروزم، پس چه می‌خواهم اگر الان در‌گرفته است."},{"v":50,"t":"اما مراتعمیدی است که بیابم و چه بسیار در تنگی هستم، تا وقتی که آن بسر‌آید."},{"v":51,"t":"آیا گمان می‌برید که من آمده‌ام تا سلامتی بر زمین بخشم؟ نی بلکه به شما می‌گویم تفریق را."},{"v":52,"t":"زیرا بعد ازاین پنج نفر که در یک خانه باشند دو از سه و سه ازدو جدا خواهند شد،"},{"v":53,"t":"پدر از پسر و پسر از پدرو مادر از دختر و دختر از مادر و خارسو ازعروس و عروس از خارسو مفارقت خواهندنمود.»"},{"v":54,"t":"آنگاه باز به آن جماعت گفت: «هنگامی که ابری بینید که از مغرب پدید آید، بی‌تامل می‌گویید باران می‌آید و چنین می‌شود."},{"v":55,"t":"و چون دیدید که باد جنوبی می‌وزد، می‌گویید گرما خواهد شد و می‌شود."},{"v":56,"t":"‌ای ریاکاران، می‌توانید صورت زمین و آسمان راتمیز دهید، پس چگونه این زمان رانمی شناسید؟"},{"v":57,"t":"و چرا از خود به انصاف حکم نمی کنید؟"},{"v":58,"t":"و هنگامی که با مدعی خود نزد حاکم می‌روی، در راه سعی کن که از او برهی، مبادا تو رانزد قاضی بکشد و قاضی تو را به‌سرهنگ سپاردو سرهنگ تو را به زندان افکند."},{"v":59,"t":"تو را می‌گویم تا فلس آخر را ادا نکنی، از آنجا هرگز بیرون نخواهی آمد.»"}],"en":[{"v":1,"t":"Meanwhile, when a multitude of many thousands had gathered together, so much so that they trampled on each other, he began to tell his disciples first of all, “Beware of the yeast of the Pharisees, which is hypocrisy."},{"v":2,"t":"But there is nothing covered up that will not be revealed, nor hidden that will not be known."},{"v":3,"t":"Therefore whatever you have said in the darkness will be heard in the light. What you have spoken in the ear in the inner rooms will be proclaimed on the housetops."},{"v":4,"t":"“I tell you, my friends, don’t be afraid of those who kill the body, and after that have no more that they can do."},{"v":5,"t":"But I will warn you whom you should fear. Fear him who after he has killed, has power to cast into Gehenna. Yes, I tell you, fear him."},{"v":6,"t":"“Aren’t five sparrows sold for two assaria coins? Not one of them is forgotten by God."},{"v":7,"t":"But the very hairs of your head are all counted. Therefore don’t be afraid. You are of more value than many sparrows."},{"v":8,"t":"“I tell you, everyone who confesses me before men, the Son of Man will also confess before the angels of God;"},{"v":9,"t":"but he who denies me in the presence of men will be denied in the presence of God’s angels."},{"v":10,"t":"Everyone who speaks a word against the Son of Man will be forgiven, but those who blaspheme against the Holy Spirit will not be forgiven."},{"v":11,"t":"When they bring you before the synagogues, the rulers, and the authorities, don’t be anxious how or what you will answer or what you will say;"},{"v":12,"t":"for the Holy Spirit will teach you in that same hour what you must say.”"},{"v":13,"t":"One of the multitude said to him, “Teacher, tell my brother to divide the inheritance with me.”"},{"v":14,"t":"But he said to him, “Man, who made me a judge or an arbitrator over you?”"},{"v":15,"t":"He said to them, “Beware! Keep yourselves from covetousness, for a man’s life doesn’t consist of the abundance of the things which he possesses.”"},{"v":16,"t":"He spoke a parable to them, saying, “The ground of a certain rich man produced abundantly."},{"v":17,"t":"He reasoned within himself, saying, ‘What will I do, because I don’t have room to store my crops?’"},{"v":18,"t":"He said, ‘This is what I will do. I will pull down my barns, build bigger ones, and there I will store all my grain and my goods."},{"v":19,"t":"I will tell my soul, “Soul, you have many goods laid up for many years. Take your ease, eat, drink, and be merry.”’"},{"v":20,"t":"“But God said to him, ‘You foolish one, tonight your soul is required of you. The things which you have prepared—whose will they be?’"},{"v":21,"t":"So is he who lays up treasure for himself, and is not rich toward God.”"},{"v":22,"t":"He said to his disciples, “Therefore I tell you, don’t be anxious for your life, what you will eat, nor yet for your body, what you will wear."},{"v":23,"t":"Life is more than food, and the body is more than clothing."},{"v":24,"t":"Consider the ravens: they don’t sow, they don’t reap, they have no warehouse or barn, and God feeds them. How much more valuable are you than birds!"},{"v":25,"t":"Which of you by being anxious can add a cubit to his height?"},{"v":26,"t":"If then you aren’t able to do even the least things, why are you anxious about the rest?"},{"v":27,"t":"Consider the lilies, how they grow. They don’t toil, neither do they spin; yet I tell you, even Solomon in all his glory was not arrayed like one of these."},{"v":28,"t":"But if this is how God clothes the grass in the field, which today exists and tomorrow is cast into the oven, how much more will he clothe you, O you of little faith?"},{"v":29,"t":"“Don’t seek what you will eat or what you will drink; neither be anxious."},{"v":30,"t":"For the nations of the world seek after all of these things, but your Father knows that you need these things."},{"v":31,"t":"But seek God’s Kingdom, and all these things will be added to you."},{"v":32,"t":"“Don’t be afraid, little flock, for it is your Father’s good pleasure to give you the Kingdom."},{"v":33,"t":"Sell what you have and give gifts to the needy. Make for yourselves purses which don’t grow old, a treasure in the heavens that doesn’t fail, where no thief approaches and no moth destroys."},{"v":34,"t":"For where your treasure is, there will your heart be also."},{"v":35,"t":"“Let your waist be dressed and your lamps burning."},{"v":36,"t":"Be like men watching for their lord when he returns from the wedding feast, that when he comes and knocks, they may immediately open to him."},{"v":37,"t":"Blessed are those servants whom the lord will find watching when he comes. Most certainly I tell you that he will dress himself, make them recline, and will come and serve them."},{"v":38,"t":"They will be blessed if he comes in the second or third watch and finds them so."},{"v":39,"t":"But know this, that if the master of the house had known in what hour the thief was coming, he would have watched and not allowed his house to be broken into."},{"v":40,"t":"Therefore be ready also, for the Son of Man is coming in an hour that you don’t expect him.”"},{"v":41,"t":"Peter said to him, “Lord, are you telling this parable to us, or to everybody?”"},{"v":42,"t":"The Lord said, “Who then is the faithful and wise steward, whom his lord will set over his household, to give them their portion of food at the right times?"},{"v":43,"t":"Blessed is that servant whom his lord will find doing so when he comes."},{"v":44,"t":"Truly I tell you that he will set him over all that he has."},{"v":45,"t":"But if that servant says in his heart, ‘My lord delays his coming,’ and begins to beat the menservants and the maidservants, and to eat and drink and to be drunken,"},{"v":46,"t":"then the lord of that servant will come in a day when he isn’t expecting him and in an hour that he doesn’t know, and will cut him in two, and place his portion with the unfaithful."},{"v":47,"t":"That servant who knew his lord’s will, and didn’t prepare nor do what he wanted, will be beaten with many stripes,"},{"v":48,"t":"but he who didn’t know, and did things worthy of stripes, will be beaten with few stripes. To whomever much is given, of him will much be required; and to whom much was entrusted, of him more will be asked."},{"v":49,"t":"“I came to throw fire on the earth. I wish it were already kindled."},{"v":50,"t":"But I have a baptism to be baptized with, and how distressed I am until it is accomplished!"},{"v":51,"t":"Do you think that I have come to give peace in the earth? I tell you, no, but rather division."},{"v":52,"t":"For from now on, there will be five in one house divided, three against two, and two against three."},{"v":53,"t":"They will be divided, father against son, and son against father; mother against daughter, and daughter against her mother; mother-in-law against her daughter-in-law, and daughter-in-law against her mother-in-law.”"},{"v":54,"t":"He said to the multitudes also, “When you see a cloud rising from the west, immediately you say, ‘A shower is coming,’ and so it happens."},{"v":55,"t":"When a south wind blows, you say, ‘There will be a scorching heat,’ and it happens."},{"v":56,"t":"You hypocrites! You know how to interpret the appearance of the earth and the sky, but how is it that you don’t interpret this time?"},{"v":57,"t":"“Why don’t you judge for yourselves what is right?"},{"v":58,"t":"For when you are going with your adversary before the magistrate, try diligently on the way to be released from him, lest perhaps he drag you to the judge, and the judge deliver you to the officer, and the officer throw you into prison."},{"v":59,"t":"I tell you, you will by no means get out of there until you have paid the very last penny.”"}],"hr":[{"v":1,"t":"Kad se uto skupilo mnoštvo, tisuće i tisuće, te su jedni druge gazili, poče Isus govoriti najprije svojim učenicima: “Čuvajte se kvasca farizejskoga, to jest licemjerja."},{"v":2,"t":"Ništa nije skriveno što se neće otkriti ni tajno što se neće saznati."},{"v":3,"t":"Naprotiv, sve što u tami rekoste, na svjetlu će se čuti; i što ste po skrovištima u uho šaptali, propovijedat će se po krovovima.”"},{"v":4,"t":"“A kažem vama, prijateljima svojim: ne bojte se onih koji ubijaju tijelo, a nakon toga nemaju više što učiniti."},{"v":5,"t":"Pokazat ću vam koga vam se bojati: onoga se bojte koji pošto ubije, ima moć baciti u pakao. Da, velim vam, njega se bojte!"},{"v":6,"t":"Ne prodaje li se pet vrapčića za dva novčića? Pa ipak ni jednoga od njih Bog ne zaboravlja."},{"v":7,"t":"A vama su i vlasi na glavi sve izbrojene. Ne bojte se! Vredniji ste nego mnogo vrabaca!”"},{"v":8,"t":"“A kažem vam: tko se god prizna mojim pred ljudima, i Sin Čovječji priznat će se njegovim pred anđelima Božjim."},{"v":9,"t":"A tko mene zaniječe pred ljudima, bit će zanijekan pred anđelima Božjim.”"},{"v":10,"t":"“I tko god rekne riječ na Sina Čovječjega, oprostit će mu se. Ali tko pohuli protiv Duha Svetoga, neće mu se oprostiti.”"},{"v":11,"t":"“Nadalje, kad vas budu dovodili pred sinagoge i poglavarstva i vlasti, ne budite zabrinuti kako ćete se ili čime braniti, što li reći!"},{"v":12,"t":"Ta Duh Sveti poučit će vas u taj čas što valja reći.”"},{"v":13,"t":"Tada mu netko iz mnoštva reče: “Učitelju, reci mome bratu da podijeli sa mnom baštinu.”"},{"v":14,"t":"Nato mu on reče: “Čovječe, tko me postavio sucem ili djeliocem nad vama?”"},{"v":15,"t":"I dometnu im: “Klonite se i čuvajte svake pohlepe: koliko god netko obilovao, život mu nije u onom što posjeduje.”"},{"v":16,"t":"Kaza im i prispodobu: “Nekomu bogatu čovjeku obilno urodi zemlja"},{"v":17,"t":"pa u sebi razmišljaše: 'Što da učinim? Nemam gdje skupiti svoju ljetinu.'"},{"v":18,"t":"I reče: 'Evo što ću učiniti! Srušit ću svoje žitnice i podignuti veće pa ću ondje zgrnuti sve žito i dobra svoja."},{"v":19,"t":"Tada ću reći duši svojoj: dušo, evo imaš u zalihi mnogo dobara za godine mnoge. Počivaj, jedi, pij, uživaj!'"},{"v":20,"t":"Ali Bog mu reče: 'Bezumniče! Već noćas duša će se tvoja zaiskati od tebe! A što si pripravio, čije će biti?'"},{"v":21,"t":"Tako biva s onim koji sebi zgrće blago, a ne bogati se u Bogu.”"},{"v":22,"t":"Zatim reče svojim učenicima: “Zato vam kažem: ne budite zabrinuti za život: što ćete jesti; ni za tijelo: u što ćete se obući."},{"v":23,"t":"Ta život je vredniji od jela i tijelo od odijela."},{"v":24,"t":"Promotrite gavrane! Ne siju niti žanju, nemaju spremišta ni žitnice, pa ipak ih Bog hrani. Koliko li ste vi vredniji od ptica!"},{"v":25,"t":"A tko od vas zabrinutošću može svojemu stasu dodati lakat?"},{"v":26,"t":"Ako dakle ni ono najmanje ne možete, što ste onda za ostalo zabrinuti?"},{"v":27,"t":"Promotrite ljiljane, kako niti predu niti tkaju, a kažem vam: ni Salomon se u svoj svojoj slavi ne zaodjenu kao jedan od njih."},{"v":28,"t":"Pa ako travu koja je danas u polju, a sutra se u peć baca Bog tako odijeva, koliko li će više vas, malovjerni!”"},{"v":29,"t":"“Zato i vi: ne tražite što ćete jesti, što piti. Ne uznemirujte se!"},{"v":30,"t":"Ta sve to traže pogani ovoga svijeta. Otac vaš zna da vam je sve to potrebno."},{"v":31,"t":"Nego, tražite kraljevstvo njegovo, a to će vam se nadodati!”"},{"v":32,"t":"“Ne boj se, stado malo: svidjelo se Ocu vašemu dati vam Kraljevstvo.”"},{"v":33,"t":"“Prodajte što god imate i dajte za milostinju! Načinite sebi kese koje ne stare, blago nepropadljivo na nebesima, kamo se kradljivac ne približava i gdje moljac ne rastače."},{"v":34,"t":"Doista, gdje vam je blago, ondje će vam i srce biti.”"},{"v":35,"t":"“Neka vam bokovi budu opasani i svjetiljke upaljene,"},{"v":36,"t":"a vi slični ljudima što čekaju gospodara kad se vraća sa svadbe da mu odmah otvore čim stigne i pokuca."},{"v":37,"t":"Blago onim slugama koje gospodar, kada dođe, nađe budne! Zaista, kažem vam, pripasat će se, posaditi ih za stol pa će pristupiti i posluživati ih."},{"v":38,"t":"Pa dođe li o drugoj ili o trećoj straži i nađe ih tako, blago njima!”"},{"v":39,"t":"“A ovo znajte: kad bi domaćin znao u koji čas kradljivac dolazi, ne bi dao prokopati kuće."},{"v":40,"t":"I vi budite pripravni jer u čas kad i ne mislite Sin Čovječji dolazi.”"},{"v":41,"t":"Nato će Petar: “Gospodine, govoriš li tu prispodobu samo za nas ili i za sve?”"},{"v":42,"t":"Reče Gospodin: “Tko li je onaj vjerni i razumni upravitelj što će ga gospodar postaviti nad svojom poslugom da im u pravo vrijeme daje obrok?"},{"v":43,"t":"Blago onome sluzi kojega gospodar kada dođe, nađe da tako radi."},{"v":44,"t":"Uistinu, kažem vam, postavit će ga nad svim imanjem svojim.”"},{"v":45,"t":"“No rekne li taj sluga u srcu: 'Okasnit će gospodar moj' pa stane tući sluge i sluškinje, jesti, piti i opijati se,"},{"v":46,"t":"doći će gospodar toga sluge u dan u koji mu se ne nada i u čas u koji i ne sluti; rasjeći će ga i dodijeliti mu udes među nevjernicima.”"},{"v":47,"t":"“I onaj sluga što je znao volju gospodara svoga, a nije bio spreman ili nije učinio po volji njegovoj, dobit će mnogo udaraca."},{"v":48,"t":"A onaj koji nije znao, ali je učinio što zaslužuje udarce, dobit će malo udaraca. Kome je god mnogo dano, od njega će se mnogo iskati. Kome je mnogo povjereno, više će se od njega iskati.”"},{"v":49,"t":"“Oganj dođoh baciti na zemlju pa što hoću ako je već planuo!"},{"v":50,"t":"Ali krstom mi se krstiti i kakve li muke za me dok se to ne izvrši!”"},{"v":51,"t":"“Mislite li da sam došao mir dati na zemlji? Nipošto, kažem vam, nego razdjeljenje."},{"v":52,"t":"Ta bit će odsada petorica u jednoj kući razdijeljena: razdijelit će se trojica protiv dvojice i dvojica protiv trojice -"},{"v":53,"t":"otac protiv sina i sin protiv oca, mati protiv kćeri i kći protiv matere, svekrva protiv snahe i snaha protiv svekrve.”"},{"v":54,"t":"Zatim je govorio mnoštvu: “Kad opazite da se oblak diže na zapadu, odmah kažete: 'Kiša će!' I bude tako."},{"v":55,"t":"Kad zapuše južnjak, kažete: 'Bit će vrućine!' I bude."},{"v":56,"t":"Licemjeri! Lice zemlje i neba umijete rasuditi, kako onda ovo vrijeme ne rasuđujete?”"},{"v":57,"t":"“Zašto sami od sebe ne sudite što je pravo?"},{"v":58,"t":"Kad s protivnikom ideš glavaru, na putu sve uloži da ga se oslobodiš pa te ne odvuče k sucu. Sudac će te predati izvršitelju, a izvršitelj baciti u tamnicu."},{"v":59,"t":"Kažem ti: nećeš izići odande dok ne isplatiš do posljednjega novčića.”"}]},"13":{"fa":[{"v":1,"t":"در آن وقت بعضی آمده او را از جلیلیانی خبر دادند که پیلاطس خون ایشان را با قربانی های ایشان آمیخته بود."},{"v":2,"t":"عیسی در جواب ایشان گفت: «آیا گمان می‌برید که این جلیلیان گناهکارتر بودند از سایر سکنه جلیل ازاین‌رو که چنین زحمات دیدند؟"},{"v":3,"t":"نی، بلکه به شما می‌گویم اگر توبه نکنید، همگی شماهمچنین هلاک خواهید شد."},{"v":4,"t":"یا آن هجده نفری که برج در سلوام بر ایشان افتاده ایشان را هلاک کرد، گمان می‌برید که از جمیع مردمان ساکن اورشلیم، خطاکارتر بودند؟"},{"v":5,"t":"حاشا، بلکه شما رامی گویم که اگر توبه نکنید همگی شما همچنین هلاک خواهید شد.»"},{"v":6,"t":"پس این مثل را آورد که «شخصی درخت انجیری در تاکستان خود غرس نمود و چون آمدتا میوه از آن بجوید، چیزی نیافت."},{"v":7,"t":"پس به باغبان گفت اینک سه سال است می‌آیم که از این درخت انجیر میوه بطلبم و نمی یابم، آن را ببر چرا زمین رانیز باطل سازد."},{"v":8,"t":"در جواب وی گفت، ای آقاامسال هم آن را مهلت ده تا گردش را کنده کودبریزم،"},{"v":9,"t":"پس اگر ثمر آورد والا بعد از آن، آن راببر.»"},{"v":10,"t":"و روز سبت در یکی از کنایس تعلیم می‌داد."},{"v":11,"t":"و اینک زنی که مدت هجده سال روح ضعف می‌داشت و منحنی شده ابد نمی توانست راست بایستد، در آنجا بود."},{"v":12,"t":"چون عیسی او را دید وی را خوانده گفت: «ای زن از ضعف خودخلاص شو.»"},{"v":13,"t":"و دست های خود را بر وی گذارد که در ساعت راست شده، خدا را تمجیدنمود."},{"v":14,"t":"آنگاه رئیس کنیسه غضب نمود، از آنروکه عیسی او را در سبت شفا داد. پس به مردم توجه نموده، گفت: «شش روز است که باید کاربکنید در آنها آمده شفا یابید، نه در روزسبت.»"},{"v":15,"t":"خداوند در جواب او گفت: «ای ریاکار، آیاهر یکی از شما در روز سبت گاو یا الاغ خود را ازآخور باز کرده بیرون نمی برد تا سیرآبش کند؟"},{"v":16,"t":"و این زنی که دختر ابراهیم است و شیطان او رامدت هجده سال تا به حال بسته بود، نمی بایست او را در روز سبت از این بند رها نمود؟»"},{"v":17,"t":"وچون این را بگفت همه مخالفان او خجل گردیدندو جمیع آن گروه شاد شدند، بسبب همه کارهای بزرگ که از وی صادر می‌گشت."},{"v":18,"t":"پس گفت: «ملکوت خدا چه چیز را می‌ماندو آن را به کدام شی تشبیه نمایم."},{"v":19,"t":"دانه خردلی راماند که شخصی گرفته در باغ خود کاشت، پس رویید و درخت بزرگ گردید، بحدی که مرغان هوا آمده در شاخه هایش آشیانه گرفتند.»"},{"v":20,"t":"باز‌گفت: «برای ملکوت خدا چه مثل آورم؟"},{"v":21,"t":"خمیرمایه‌ای را می‌ماند که زنی گرفته در سه پیمانه آرد پنهان ساخت تا همه مخمرشد.»"},{"v":22,"t":"و در شهرها و دهات گشته، تعلیم می‌داد وبه سوی اورشلیم سفر می‌کرد،"},{"v":23,"t":"که شخصی به وی گفت: «ای خداوند آیا کم هستند که نجات یابند؟» او به ایشان گفت:"},{"v":24,"t":"«جد و جهد کنید تااز در تنگ داخل شوید. زیرا که به شما می‌گویم بسیاری طلب دخول خواهند کرد و نخواهندتوانست."},{"v":25,"t":"بعد از آنکه صاحب‌خانه برخیزد ودر را ببندد و شما بیرون ایستاده در را کوبیدن آغاز کنید و گویید خداوندا خداوندا برای ما بازکن. آنگاه وی در جواب خواهد گفت شما رانمی شناسم که از کجا هستید."},{"v":26,"t":"در آن وقت خواهید گفت که در حضور تو خوردیم وآشامیدیم و در کوچه های ما تعلیم دادی."},{"v":27,"t":"بازخواهد گفت، به شما می‌گویم که شما رانمی شناسم از کجا هستید؟ ای همه بدکاران از من دور شوید."},{"v":28,"t":"در آنجا گریه و فشار دندان خواهدبود، چون ابراهیم واسحق و یعقوب و جمیع انبیارا در ملکوت خدا بینید و خود را بیرون افکنده یابید"},{"v":29,"t":"و از مشرق و مغرب و شمال و جنوب آمده در ملکوت خدا خواهند نشست."},{"v":30,"t":"و اینک آخرین هستند که اولین خواهند بود و اولین که آخرین خواهند بود.»"},{"v":31,"t":"در همان روز چند نفر از فریسیان آمده به وی گفتند: «دور شو و از اینجا برو زیرا که هیرودیس می‌خواهد تو را به قتل رساند.»"},{"v":32,"t":"ایشان را گفت: «بروید و به آن روباه گوییداینک امروز و فردا دیوها را بیرون می‌کنم ومریضان را صحت می‌بخشم و در روز سوم کامل خواهم شد."},{"v":33,"t":"لیکن می‌باید امروز و فردا و پس‌فردا راه روم، زیرا که محال است نبی بیرون ازاورشلیم کشته شود."},{"v":34,"t":"‌ای اورشلیم، ای اورشلیم که قاتل انبیا و سنگسار کننده مرسلین خودهستی، چند کرت خواستم اطفال تو را جمع کنم، چنانکه مرغ جوجه های خویش را زیر بالهای خود می‌گیرد و نخواستید."},{"v":35,"t":"اینک خانه شمابرای شما خراب گذاشته می‌شود و به شمامی گویم که مرا دیگر نخواهید دید تا وقتی آیدکه گویید مبارک است او که به نام خداوندمی آید.»"}],"en":[{"v":1,"t":"Now there were some present at the same time who told him about the Galileans whose blood Pilate had mixed with their sacrifices."},{"v":2,"t":"Jesus answered them, “Do you think that these Galileans were worse sinners than all the other Galileans, because they suffered such things?"},{"v":3,"t":"I tell you, no, but unless you repent, you will all perish in the same way."},{"v":4,"t":"Or those eighteen on whom the tower in Siloam fell and killed them—do you think that they were worse offenders than all the men who dwell in Jerusalem?"},{"v":5,"t":"I tell you, no, but, unless you repent, you will all perish in the same way.”"},{"v":6,"t":"He spoke this parable. “A certain man had a fig tree planted in his vineyard, and he came seeking fruit on it and found none."},{"v":7,"t":"He said to the vine dresser, ‘Behold, these three years I have come looking for fruit on this fig tree, and found none. Cut it down! Why does it waste the soil?’"},{"v":8,"t":"He answered, ‘Lord, leave it alone this year also, until I dig around it and fertilize it."},{"v":9,"t":"If it bears fruit, fine; but if not, after that, you can cut it down.’”"},{"v":10,"t":"He was teaching in one of the synagogues on the Sabbath day."},{"v":11,"t":"Behold, there was a woman who had a spirit of infirmity eighteen years. She was bent over and could in no way straighten herself up."},{"v":12,"t":"When Jesus saw her, he called her and said to her, “Woman, you are freed from your infirmity.”"},{"v":13,"t":"He laid his hands on her, and immediately she stood up straight and glorified God."},{"v":14,"t":"The ruler of the synagogue, being indignant because Jesus had healed on the Sabbath, said to the multitude, “There are six days in which men ought to work. Therefore come on those days and be healed, and not on the Sabbath day!”"},{"v":15,"t":"Therefore the Lord answered him, “You hypocrites! Doesn’t each one of you free his ox or his donkey from the stall on the Sabbath and lead him away to water?"},{"v":16,"t":"Ought not this woman, being a daughter of Abraham whom Satan had bound eighteen long years, be freed from this bondage on the Sabbath day?”"},{"v":17,"t":"As he said these things, all his adversaries were disappointed; and all the multitude rejoiced for all the glorious things that were done by him."},{"v":18,"t":"He said, “What is God’s Kingdom like? To what shall I compare it?"},{"v":19,"t":"It is like a grain of mustard seed which a man took and put in his own garden. It grew and became a large tree, and the birds of the sky live in its branches.”"},{"v":20,"t":"Again he said, “To what shall I compare God’s Kingdom?"},{"v":21,"t":"It is like yeast, which a woman took and hid in three measures of flour, until it was all leavened.”"},{"v":22,"t":"He went on his way through cities and villages, teaching, and traveling on to Jerusalem."},{"v":23,"t":"One said to him, “Lord, are they few who are saved?” He said to them,"},{"v":24,"t":"“Strive to enter in by the narrow door, for many, I tell you, will seek to enter in and will not be able."},{"v":25,"t":"When once the master of the house has risen up and has shut the door, and you begin to stand outside and to knock at the door, saying, ‘Lord, Lord, open to us!’ then he will answer and tell you, ‘I don’t know you or where you come from.’"},{"v":26,"t":"Then you will begin to say, ‘We ate and drank in your presence, and you taught in our streets.’"},{"v":27,"t":"He will say, ‘I tell you, I don’t know where you come from. Depart from me, all you workers of iniquity.’"},{"v":28,"t":"There will be weeping and gnashing of teeth when you see Abraham, Isaac, Jacob, and all the prophets in God’s Kingdom, and yourselves being thrown outside."},{"v":29,"t":"They will come from the east, west, north, and south, and will sit down in God’s Kingdom."},{"v":30,"t":"Behold, there are some who are last who will be first, and there are some who are first who will be last.”"},{"v":31,"t":"On that same day, some Pharisees came, saying to him, “Get out of here and go away, for Herod wants to kill you.”"},{"v":32,"t":"He said to them, “Go and tell that fox, ‘Behold, I cast out demons and perform cures today and tomorrow, and the third day I complete my mission."},{"v":33,"t":"Nevertheless I must go on my way today and tomorrow and the next day, for it can’t be that a prophet would perish outside of Jerusalem.’"},{"v":34,"t":"“Jerusalem, Jerusalem, you who kills the prophets and stones those who are sent to her! How often I wanted to gather your children together, like a hen gathers her own brood under her wings, and you refused!"},{"v":35,"t":"Behold, your house is left to you desolate. I tell you, you will not see me until you say, ‘Blessed is he who comes in the name of the Lord!’”"}],"hr":[{"v":1,"t":"Upravo u taj čas dođoše neki te mu javiše što se dogodilo s Galilejcima kojih je krv Pilat pomiješao s krvlju njihovih žrtava."},{"v":2,"t":"Isus im odgovori: “Mislite li da ti Galilejci, jer tako postradaše, bijahu grešniji od drugih Galilejaca?"},{"v":3,"t":"Nipošto, kažem vam, nego ako se ne obratite, svi ćete slično propasti!"},{"v":4,"t":"Ili onih osamnaest na koje se srušila kula u Siloamu i ubila ih, zar mislite da su oni bili veći dužnici od svih Jeruzalemaca?"},{"v":5,"t":"Nipošto, kažem vam, nego ako se ne obratite, svi ćete tako propasti.”"},{"v":6,"t":"Nato im pripovjedi ovu prispodobu: “Imao netko smokvu zasađenu u svom vinogradu. Dođe tražeć ploda na njoj i ne nađe"},{"v":7,"t":"pa reče vinogradaru: 'Evo, već tri godine dolazim i tražim ploda na ovoj smokvi i ne nalazim. Posijeci je. Zašto da iscrpljuje zemlju?'"},{"v":8,"t":"A on mu odgovori: 'Gospodaru, ostavi je još ove godine dok je ne okopam i ne pognojim."},{"v":9,"t":"Možda će ubuduće ipak uroditi. Ako li ne, posjeći ćeš je.'”"},{"v":10,"t":"Jedne je subote naučavao u nekoj sinagogi."},{"v":11,"t":"Kad eto žene koja je osamnaest godina imala duha bolesti. Bila je zgrbljena i nikako se nije mogla uspraviti."},{"v":12,"t":"Kad je Isus opazi, dozva je i reče joj: “Ženo, oslobođena si svoje bolesti!”"},{"v":13,"t":"I položi na nju ruke, a ona se umah uspravi i poče slaviti Boga."},{"v":14,"t":"Nadstojnik sinagoge - ozlovoljen što je Isus u subotu izliječio - govoraše mnoštvu: “Šest je dana u koje treba raditi! U te dakle dane dolazite i liječite se, a ne u dan subotni!”"},{"v":15,"t":"Odgovori mu Gospodin: “Licemjeri! Ne driješi li svaki od vas u subotu svoga vola ili magarca od jasala da ga vodi na vodu?"},{"v":16,"t":"Nije li dakle i ovu kćer Abrahamovu, koju Sotona sveza evo osamnaest je već godina, trebalo odriješiti od tih spona u dan subotni?”"},{"v":17,"t":"Na te njegove riječi postidješe se svi protivnici njegovi, a sav se narod radovaše zbog svega čime se on proslavio."},{"v":18,"t":"Govoraše dakle: “Čemu je slično kraljevstvo Božje? Čemu da ga prispodobim?"},{"v":19,"t":"Ono je kao kad čovjek uze gorušičino zrno i baci ga u svoj vrt. Uzraste i razvi se u stablo te mu se ptice nebeske gnijezde po granama.”"},{"v":20,"t":"I opet im reče: “Čemu da prispodobim kraljevstvo Božje?"},{"v":21,"t":"Ono je kao kad žena uze kvasac i zamijesi ga u tri mjere brašna dok sve ne uskisne.”"},{"v":22,"t":"Putujući tako u Jeruzalem, prolazio je i naučavao gradovima i selima."},{"v":23,"t":"Reče mu tada netko: “Gospodine, je li malo onih koji se spasavaju?” A on im reče:"},{"v":24,"t":"“Borite se da uđete na uska vrata jer mnogi će, velim vam, tražiti da uđu, ali neće moći.”"},{"v":25,"t":"“Kada gospodar kuće ustane i zaključa vrata, a vi stojeći vani počnete kucati na vrata: 'Gospodine, otvori nam!', on će vam odgovoriti: 'Ne znam vas odakle ste!'"},{"v":26,"t":"Tada ćete početi govoriti: 'Pa mi smo s tobom jeli i pili, po našim si trgovima naučavao!'"},{"v":27,"t":"A on će vam reći: 'Kažem vam: ne znam odakle ste. Odstupite od mene, svi zlotvori!'”"},{"v":28,"t":"“Ondje će biti plač i škrgut zubi kad ugledate Abrahama i Izaka i Jakova i sve proroke u kraljevstvu Božjem, a sebe vani, izbačene."},{"v":29,"t":"I doći će s istoka i zapada, sa sjevera i juga i sjesti za stol u kraljevstvu Božjem."},{"v":30,"t":"Evo, ima posljednjih koji će biti prvi, ima i prvih koji će biti posljednji.”"},{"v":31,"t":"U taj čas pristupe neki farizeji i reknu mu: “Otiđi, otputuj odavde jer te Herod hoće ubiti.”"},{"v":32,"t":"A on će njima: “Idite i kažite toj lisici: 'Evo, izgonim đavle i liječim danas i sutra, a treći dan dovršujem."},{"v":33,"t":"Ali danas, sutra i prekosutra moram nastaviti put jer ne priliči da prorok pogine izvan Jeruzalema.'”"},{"v":34,"t":"“Jeruzaleme, Jeruzaleme, koji ubijaš proroke i kamenuješ one što su tebi poslani! Koliko li puta htjedoh skupiti djecu tvoju kao kvočka piliće pod krila i ne htjedoste!"},{"v":35,"t":"Evo, napuštena vam kuća. A kažem vam, nećete me vidjeti dok ne dođe čas te reknete: “Blagoslovljen Onaj koji dolazi u ime Gospodnje!”"}]},"14":{"fa":[{"v":1,"t":"و واقع شد که در روز سبت، به خانه یکی از روسای فریسیان برای غذاخوردن درآمد و ایشان مراقب او می‌بودند،"},{"v":2,"t":"واینک شخصی مستسقی پیش او بود،"},{"v":3,"t":"آنگاه عیسی ملتفت شده فقها و فریسیان را خطاب کرده، گفت: «آیا در روز سبت شفا دادن جایزاست؟»"},{"v":4,"t":"ایشان ساکت ماندند. پس آن مرد راگرفته، شفا داد و رها کرد."},{"v":5,"t":"و به ایشان روی آورده، گفت: «کیست از شما که الاغ یا گاوش روزسبت در چاهی افتد و فور آن را بیرون نیاورد؟»"},{"v":6,"t":"پس در این امور از جواب وی عاجزماندند."},{"v":7,"t":"و برای مهمانان مثلی زد، چون ملاحظه فرمود که چگونه صدر مجلس را اختیارمی کردند. پس به ایشان گفت:"},{"v":8,"t":"«چون کسی تو رابه عروسی دعوت کند، در صدر مجلس منشین، مبادا کسی بزرگتر از تو را هم وعده خواسته باشد."},{"v":9,"t":"پس آن کسی‌که تو و او را وعده خواسته بودبیاید و تو را گوید این کس را جای بده و تو باخجالت روی به صف نعال خواهی نهاد."},{"v":10,"t":"بلکه چون مهمان کسی باشی، رفته در پایین بنشین تاوقتی که میزبانت آید به تو گوید، ای دوست برترنشین آنگاه تو را در حضور مجلسیان عزت خواهد بود."},{"v":11,"t":"زیرا هر‌که خود را بزرگ سازدذلیل گردد و هر‌که خویشتن را فرود آرد، سرافرازگردد.»"},{"v":12,"t":"پس به آن کسی‌که از او وعده خواسته بود نیز گفت: «وقتی که چاشت یا شام دهی دوستان یا برادران یا خویشان یا همسایگان دولتمند خود را دعوت مکن مبادا ایشان نیز تو رابخوانند و تو را عوض داده شود."},{"v":13,"t":"بلکه چون ضیافت کنی، فقیران و لنگان و شلان و کوران رادعوت کن."},{"v":14,"t":"که خجسته خواهی بود زیرا ندارندکه تو را عوض دهند و در قیامت عادلان، به توجزا عطا خواهد شد.»"},{"v":15,"t":"آنگاه یکی از مجلسیان چون این سخن راشنید گفت: «خوشابحال کسی‌که در ملکوت خداغذا خورد.»"},{"v":16,"t":"به وی گفت: «شخصی ضیافتی عظیم نمود و بسیاری را دعوت نمود."},{"v":17,"t":"پس چون وقت شام رسید، غلام خود را فرستاد تادعوت‌شدگان را گوید، بیایید زیرا که الحال همه‌چیز حاضر است."},{"v":18,"t":"لیکن همه به یک رای عذرخواهی آغاز کردند. اولی گفت: مزرعه‌ای خریدم و ناچار باید بروم آن را ببینم، از توخواهش دارم مرا معذور داری."},{"v":19,"t":"و دیگری گفت: پنج جفت گاو خریده‌ام، می‌روم تا آنها رابیازمایم، به تو التماس دارم مرا عفو نمایی."},{"v":20,"t":"سومی گفت: زنی گرفته‌ام و از این سبب نمی توانم بیایم."},{"v":21,"t":"پس آن غلام آمده مولای خود را از این امور مطلع ساخت. آنگاه صاحب‌خانه غضب نموده به غلام خود فرمود: به بازارهاو کوچه های شهر بشتاب و فقیران و لنگان وشلان و کوران را در اینجا بیاور."},{"v":22,"t":"پس غلام گفت: ای آقا آنچه فرمودی شد و هنوز جای باقی است."},{"v":23,"t":"پس آقا به غلام گفت: به راهها و مرزهابیرون رفته، مردم را به الحاح بیاور تا خانه من پرشود."},{"v":24,"t":"زیرا به شما می‌گویم هیچ‌یک از آنانی که دعوت شده بودند، شام مرا نخواهد چشید.»"},{"v":25,"t":"و هنگامی که جمعی کثیر همراه اومی رفتند، روی گردانیده بدیشان گفت:"},{"v":26,"t":"«اگرکسی نزد من آید و پدر، مادر و زن و اولاد وبرادران و خواهران، حتی جان خود را نیز دشمن ندارد، شاگرد من نمی تواند بود."},{"v":27,"t":"و هر‌که صلیب خود را برندارد و از عقب من نیاید، نمی تواندشاگرد من گردد."},{"v":28,"t":"«زیرا کیست از شما که قصد بنای برجی داشته باشد و اول ننشیند تا برآورد خرج آن رابکند که آیا قوت تمام کردن آن دارد یا نه؟"},{"v":29,"t":"که مبادا چون بنیادش نهاد و قادر بر تمام کردنش نشد، هر‌که بیند تمسخرکنان گوید،"},{"v":30,"t":"این شخص عمارتی شروع کرده نتوانست به انجامش رساند."},{"v":31,"t":"یا کدام پادشاه است که برای مقاتله باپادشاه دیگر برود، جز اینکه اول نشسته تامل نماید که آیا با ده هزار سپاه، قدرت مقاومت کسی را دارد که با بیست هزار لشکر بر وی می‌آید؟"},{"v":32,"t":"والا چون او هنوز دور است ایلچی‌ای فرستاده شروط صلح را ازاو درخواست کند."},{"v":33,"t":"«پس همچنین هر یکی از شما که تمام مایملک خود را ترک نکند، نمی تواند شاگرد من شود."},{"v":34,"t":"«نمک نیکو است ولی هرگاه نمک فاسدشد به چه چیز اصلاح پذیرد؟"},{"v":35,"t":"نه برای زمین مصرفی دارد و نه برای مزبله، بلکه بیرونش می‌ریزند. آنکه گوش شنوا دارد بشنود.»"}],"en":[{"v":1,"t":"When he went into the house of one of the rulers of the Pharisees on a Sabbath to eat bread, they were watching him."},{"v":2,"t":"Behold, a certain man who had dropsy was in front of him."},{"v":3,"t":"Jesus, answering, spoke to the lawyers and Pharisees, saying, “Is it lawful to heal on the Sabbath?”"},{"v":4,"t":"But they were silent. He took him, and healed him, and let him go."},{"v":5,"t":"He answered them, “Which of you, if your son or an ox fell into a well, wouldn’t immediately pull him out on a Sabbath day?”"},{"v":6,"t":"They couldn’t answer him regarding these things."},{"v":7,"t":"He spoke a parable to those who were invited, when he noticed how they chose the best seats, and said to them,"},{"v":8,"t":"“When you are invited by anyone to a wedding feast, don’t sit in the best seat, since perhaps someone more honorable than you might be invited by him,"},{"v":9,"t":"and he who invited both of you would come and tell you, ‘Make room for this person.’ Then you would begin, with shame, to take the lowest place."},{"v":10,"t":"But when you are invited, go and sit in the lowest place, so that when he who invited you comes, he may tell you, ‘Friend, move up higher.’ Then you will be honored in the presence of all who sit at the table with you."},{"v":11,"t":"For everyone who exalts himself will be humbled, and whoever humbles himself will be exalted.”"},{"v":12,"t":"He also said to the one who had invited him, “When you make a dinner or a supper, don’t call your friends, nor your brothers, nor your kinsmen, nor rich neighbors, or perhaps they might also return the favor, and pay you back."},{"v":13,"t":"But when you make a feast, ask the poor, the maimed, the lame, or the blind;"},{"v":14,"t":"and you will be blessed, because they don’t have the resources to repay you. For you will be repaid in the resurrection of the righteous.”"},{"v":15,"t":"When one of those who sat at the table with him heard these things, he said to him, “Blessed is he who will feast in God’s Kingdom!”"},{"v":16,"t":"But he said to him, “A certain man made a great supper, and he invited many people."},{"v":17,"t":"He sent out his servant at supper time to tell those who were invited, ‘Come, for everything is ready now.’"},{"v":18,"t":"They all as one began to make excuses. “The first said to him, ‘I have bought a field, and I must go and see it. Please have me excused.’"},{"v":19,"t":"“Another said, ‘I have bought five yoke of oxen, and I must go try them out. Please have me excused.’"},{"v":20,"t":"“Another said, ‘I have married a wife, and therefore I can’t come.’"},{"v":21,"t":"“That servant came, and told his lord these things. Then the master of the house, being angry, said to his servant, ‘Go out quickly into the streets and lanes of the city, and bring in the poor, maimed, blind, and lame.’"},{"v":22,"t":"“The servant said, ‘Lord, it is done as you commanded, and there is still room.’"},{"v":23,"t":"“The lord said to the servant, ‘Go out into the highways and hedges, and compel them to come in, that my house may be filled."},{"v":24,"t":"For I tell you that none of those men who were invited will taste of my supper. For many are called, but few are chosen.’”"},{"v":25,"t":"Now great multitudes were going with him. He turned and said to them,"},{"v":26,"t":"“If anyone comes to me, and doesn’t disregard his own father, mother, wife, children, brothers, and sisters, yes, and his own life also, he can’t be my disciple."},{"v":27,"t":"Whoever doesn’t bear his own cross and come after me, can’t be my disciple."},{"v":28,"t":"For which of you, desiring to build a tower, doesn’t first sit down and count the cost, to see if he has enough to complete it?"},{"v":29,"t":"Or perhaps, when he has laid a foundation and isn’t able to finish, everyone who sees begins to mock him,"},{"v":30,"t":"saying, ‘This man began to build and wasn’t able to finish.’"},{"v":31,"t":"Or what king, as he goes to encounter another king in war, will not sit down first and consider whether he is able with ten thousand to meet him who comes against him with twenty thousand?"},{"v":32,"t":"Or else, while the other is yet a great way off, he sends an envoy and asks for conditions of peace."},{"v":33,"t":"So therefore, whoever of you who doesn’t renounce all that he has, he can’t be my disciple."},{"v":34,"t":"“Salt is good, but if the salt becomes flat and tasteless, with what do you season it?"},{"v":35,"t":"It is fit neither for the soil nor for the manure pile. It is thrown out. He who has ears to hear, let him hear.”"}],"hr":[{"v":1,"t":"Jedne subote dođe on u kuću nekoga prvaka farizejskog na objed. A oni ga vrebahu."},{"v":2,"t":"Kad evo: pred njim neki čovjek koji je imao vodenu bolest."},{"v":3,"t":"Nato Isus upita zakonoznance i farizeje: “Je li dopušteno subotom liječiti ili nije?”"},{"v":4,"t":"A oni mukom ponikoše. On ga dotaknu, izliječi i otpusti."},{"v":5,"t":"A njima reče: “Ako komu od vas sin ili vol padne u bunar, neće li ga brže bolje izvući i u dan subotni?”"},{"v":6,"t":"I ne mogoše mu na to odgovoriti."},{"v":7,"t":"Promatrajući kako uzvanici biraju prva mjesta, kaza im prispodobu:"},{"v":8,"t":"“Kada te tko pozove na svadbu, ne sjedaj na prvo mjesto da ne bi možda bio pozvan koji časniji od tebe,"},{"v":9,"t":"te ne dođe onaj koji je pozvao tebe i njega i ne rekne ti: 'Ustupi mjesto ovome.' Tada ćeš, postiđen, morati zauzeti posljednje mjesto."},{"v":10,"t":"Nego kad budeš pozvan, idi i sjedni na posljednje mjesto pa, kada dođe onaj koji te pozvao, da ti rekne: 'Prijatelju, pomakni se naviše!' Bit će ti to tada na čast pred svim sustolnicima,"},{"v":11,"t":"jer - svaki koji se uzvisuje, bit će ponižen, a koji se ponizuje, bit će uzvišen.”"},{"v":12,"t":"A i onome koji ga pozva, kaza: “Kad priređuješ objed ili večeru, ne pozivaj svojih prijatelja, ni braće, ni rodbine, ni bogatih susjeda, da ne bi možda i oni tebe pozvali i tako ti uzvratili."},{"v":13,"t":"Nego kad priređuješ gozbu, pozovi siromahe, sakate, hrome, slijepe."},{"v":14,"t":"Blago tebi jer oni ti nemaju čime uzvratiti. Uzvratit će ti se doista o uskrsnuću pravednih.”"},{"v":15,"t":"Kad je to čuo jedan od sustolnika, reče mu: “Blago onome koji bude blagovao u kraljevstvu Božjem!”"},{"v":16,"t":"A on mu reče: “Čovjek neki priredi veliku večeru i pozva mnoge."},{"v":17,"t":"I posla slugu u vrijeme večere da rekne uzvanicima: 'Dođite! Već je pripravljeno!'"},{"v":18,"t":"A oni se odreda počeli ispričavati. Prvi mu reče: 'Njivu sam kupio i valja mi poći pogledati je. Molim te, ispričaj me.'"},{"v":19,"t":"Drugi reče: 'Kupio sam pet jarmova volova pa idem okušati ih. Molim te, ispričaj me.'"},{"v":20,"t":"Treći reče: 'Oženio sam se i zato ne mogu doći.'”"},{"v":21,"t":"“Sluga se vrati i javi to domaćinu. Tada domaćin, gnjevan, reče sluzi: 'Iziđi brzo na trgove gradske i ulice pa dovedi ovamo prosjake, sakate, slijepe i hrome.'"},{"v":22,"t":"I sluga reče: 'Gospodaru, učinjeno je što si naredio i još ima mjesta.'"},{"v":23,"t":"Reče gospodar sluzi: 'Iziđi na putove i među ograde i prisili neka uđu da mi se napuni kuća.'"},{"v":24,"t":"A kažem vam: nijedan od onih pozvanih neće okusiti moje večere.”"},{"v":25,"t":"S njim je zajedno putovalo silno mnoštvo. On se okrene i reče im:"},{"v":26,"t":"“Dođe li tko k meni, a ne mrzi svog oca i majku, ženu i djecu, braću i sestre, pa i sam svoj život, ne može biti moj učenik!"},{"v":27,"t":"I tko ne nosi svoga križa i ne ide za mnom, ne može biti moj učenik!”"},{"v":28,"t":"“Tko od vas, nakan graditi kulu, neće prije sjesti i proračunati troškove ima li čime dovršiti:"},{"v":29,"t":"da ga ne bi - pošto već postavi temelj, a ne mogne dovršiti - počeli ismjehivati svi koji to vide:"},{"v":30,"t":"'Ovaj čovjek poče graditi, a ne može dovršiti!'"},{"v":31,"t":"Ili koji kralj kad polazi da se zarati s drugim kraljem, neće prije sjesti i promisliti da li s deset tisuća može presresti onoga koji na nj dolazi s dvadeset tisuća?"},{"v":32,"t":"Ako ne može, dok je onaj još daleko, poslat će poslanstvo da zaište mir.”"},{"v":33,"t":"“Tako dakle nijedan od vas koji se ne odrekne svega što posjeduje, ne može biti moj učenik.”"},{"v":34,"t":"“Dobra je sol. Ali ako i sol obljutavi, čime će se ona začiniti?"},{"v":35,"t":"Nije prikladna ni za zemlju ni za gnojište. Van se baca. Tko ima uši da čuje, neka čuje!”"}]},"15":{"fa":[{"v":1,"t":"و چون همه باجگیران و گناهکاران به نزدش می‌آمدند تا کلام او را بشنوند،"},{"v":2,"t":"فریسیان و کاتبان، همهمه‌کنان می‌گفتند: «این شخص، گناهکارن را می‌پذیرد و با ایشان می‌خورد.»"},{"v":3,"t":"پس برای ایشان این مثل را زده، گفت:"},{"v":4,"t":"«کیست از شما که صد گوسفند داشته باشد و یکی از آنها گم شود که آن نود و نه را درصحرا نگذارد و از عقب آن گمشده نرود تا آن رابیابد؟"},{"v":5,"t":"پس چون آن را یافت به شادی بر دوش خود می‌گذارد،"},{"v":6,"t":"و به خانه آمده، دوستان وهمسایگان را می‌طلبد و بدیشان می‌گوید با من شادی کنید زیرا گوسفند گمشده خود را یافته‌ام."},{"v":7,"t":"به شما می‌گویم که بر این منوال خوشی درآسمان رخ می‌نماید به‌سبب توبه یک گناهکاربیشتر از برای نود و نه عادل که احتیاج به توبه ندارند."},{"v":8,"t":"یا کدام زن است که ده درهم داشته باشدهرگاه یک درهم گم شود، چراغی افروخته، خانه را جاروب نکند و به دقت تفحص ننماید تا آن رابیابد؟"},{"v":9,"t":"و چون یافت دوستان و همسایگان خودرا جمع کرده می‌گوید با من شادی کنید زیرادرهم گمشده را پیدا کرده‌ام."},{"v":10,"t":"همچنین به شمامی گویم شادی برای فرشتگان خدا روی می‌دهدبه‌سبب یک خطاکار که توبه کند.»"},{"v":11,"t":"باز‌گفت: «شخصی را دو پسر بود."},{"v":12,"t":"روزی پسر کوچک به پدر خود گفت: ای پدر، رصداموالی که باید به من رسد، به من بده. پس اومایملک خود را بر این دو تقسیم کرد."},{"v":13,"t":"و چندی نگذشت که آن پسر کهتر، آنچه داشت جمع کرده، به ملکی بعید کوچ کرد و به عیاشی ناهنجار، سرمایه خود را تلف نمود."},{"v":14,"t":"و چون تمام راصرف نموده بود، قحطی سخت در آن دیارحادث گشت و او به محتاج شدن شروع کرد."},{"v":15,"t":"پس رفته خود را به یکی از اهل آن ملک پیوست. وی او را به املاک خود فرستاد تاگرازبانی کند."},{"v":16,"t":"و آرزو می‌داشت که شکم خودرا از خرنوبی که خوکان می‌خوردند سیر کند وهیچ‌کس او را چیزی نمی داد."},{"v":17,"t":"«آخر به خود آمده، گفت چقدر از مزدوران پدرم نان فراوان دارند و من از گرسنگی هلاک می‌شوم،"},{"v":18,"t":"برخاسته نزد پدر خود می‌روم و بدوخواهم گفت‌ای پدر به آسمان و به حضور تو گناه کرده‌ام،"},{"v":19,"t":"و دیگر شایسته آن نیستم که پسر توخوانده شوم، مرا چون یکی از مزدوران خودبگیر."},{"v":20,"t":"در ساعت برخاسته به سوی پدر خودمتوجه شد. اما هنوز دور بود که پدرش او را دیده، ترحم نمود و دوان دوان آمده او را در آغوش خود کشیده، بوسید."},{"v":21,"t":"پسر وی را گفت، ای پدربه آسمان و به حضور تو گناه کرده‌ام و بعد از این لایق آن نیستم که پسر تو خوانده شوم."},{"v":22,"t":"لیکن پدر به غلامان خود گفت، جامه بهترین را از خانه آورده بدو بپوشانید و انگشتری بر دستش کنید ونعلین بر پایهایش،"},{"v":23,"t":"و گوساله پرواری را آورده ذبح کنید تا بخوریم و شادی نماییم."},{"v":24,"t":"زیرا که این پسر من مرده بود، زنده گردید و گم شده بود، یافت شد. پس به شادی کردن شروع نمودند."},{"v":25,"t":"اما پسر بزرگ او در مزرعه بود. چون آمده نزدیک به خانه رسید، صدای ساز و رقص راشنید."},{"v":26,"t":"پس یکی از نوکران خود را طلبیده پرسید این چیست؟"},{"v":27,"t":"به وی عرض کرد برادرت آمده و پدرت گوساله پرواری را ذبح کرده است زیرا که او را صحیح باز‌یافت."},{"v":28,"t":"ولی او خشم نموده نخواست به خانه درآید تا پدرش بیرون آمده به او التماس نمود."},{"v":29,"t":"اما او در جواب پدرخود گفت، اینک سالها است که من خدمت توکرده‌ام و هرگز از حکم تو تجاوز نورزیده و هرگزبزغاله‌ای به من ندادی تا با دوستان خود شادی کنم."},{"v":30,"t":"لیکن چون این پسرت آمد که دولت تو رابا فاحشه‌ها تلف کرده است، برای او گوساله پرواری را ذبح کردی."},{"v":31,"t":"او وی را گفت، ای فرزند تو همیشه با من هستی و آنچه از آن من است، مال تو است."},{"v":32,"t":"ولی می‌بایست شادمانی کرد و مسرور شد زیرا که این برادر تو مرده بود، زنده گشت و گم شده بود، یافت گردید.»"}],"en":[{"v":1,"t":"Now all the tax collectors and sinners were coming close to him to hear him."},{"v":2,"t":"The Pharisees and the scribes murmured, saying, “This man welcomes sinners, and eats with them.”"},{"v":3,"t":"He told them this parable:"},{"v":4,"t":"“Which of you men, if you had one hundred sheep and lost one of them, wouldn’t leave the ninety-nine in the wilderness and go after the one that was lost, until he found it?"},{"v":5,"t":"When he has found it, he carries it on his shoulders, rejoicing."},{"v":6,"t":"When he comes home, he calls together his friends and his neighbors, saying to them, ‘Rejoice with me, for I have found my sheep which was lost!’"},{"v":7,"t":"I tell you that even so there will be more joy in heaven over one sinner who repents, than over ninety-nine righteous people who need no repentance."},{"v":8,"t":"“Or what woman, if she had ten drachma coins, if she lost one drachma coin, wouldn’t light a lamp, sweep the house, and seek diligently until she found it?"},{"v":9,"t":"When she has found it, she calls together her friends and neighbors, saying, ‘Rejoice with me, for I have found the drachma which I had lost!’"},{"v":10,"t":"Even so, I tell you, there is joy in the presence of the angels of God over one sinner repenting.”"},{"v":11,"t":"He said, “A certain man had two sons."},{"v":12,"t":"The younger of them said to his father, ‘Father, give me my share of your property.’ So he divided his livelihood between them."},{"v":13,"t":"Not many days after, the younger son gathered all of this together and traveled into a far country. There he wasted his property with riotous living."},{"v":14,"t":"When he had spent all of it, there arose a severe famine in that country, and he began to be in need."},{"v":15,"t":"He went and joined himself to one of the citizens of that country, and he sent him into his fields to feed pigs."},{"v":16,"t":"He wanted to fill his belly with the pods that the pigs ate, but no one gave him any."},{"v":17,"t":"But when he came to himself, he said, ‘How many hired servants of my father’s have bread enough to spare, and I’m dying with hunger!"},{"v":18,"t":"I will get up and go to my father, and will tell him, “Father, I have sinned against heaven and in your sight."},{"v":19,"t":"I am no more worthy to be called your son. Make me as one of your hired servants.”’"},{"v":20,"t":"“He arose and came to his father. But while he was still far off, his father saw him and was moved with compassion, and ran, fell on his neck, and kissed him."},{"v":21,"t":"The son said to him, ‘Father, I have sinned against heaven and in your sight. I am no longer worthy to be called your son.’"},{"v":22,"t":"“But the father said to his servants, ‘Bring out the best robe and put it on him. Put a ring on his hand and sandals on his feet."},{"v":23,"t":"Bring the fattened calf, kill it, and let’s eat and celebrate;"},{"v":24,"t":"for this, my son, was dead and is alive again. He was lost and is found.’ Then they began to celebrate."},{"v":25,"t":"“Now his elder son was in the field. As he came near to the house, he heard music and dancing."},{"v":26,"t":"He called one of the servants to him and asked what was going on."},{"v":27,"t":"He said to him, ‘Your brother has come, and your father has killed the fattened calf, because he has received him back safe and healthy.’"},{"v":28,"t":"But he was angry and would not go in. Therefore his father came out and begged him."},{"v":29,"t":"But he answered his father, ‘Behold, these many years I have served you, and I never disobeyed a commandment of yours, but you never gave me a goat, that I might celebrate with my friends."},{"v":30,"t":"But when this your son came, who has devoured your living with prostitutes, you killed the fattened calf for him.’"},{"v":31,"t":"“He said to him, ‘Son, you are always with me, and all that is mine is yours."},{"v":32,"t":"But it was appropriate to celebrate and be glad, for this, your brother, was dead, and is alive again. He was lost, and is found.’”"}],"hr":[{"v":1,"t":"Okupljahu se oko njega svi carinici i grešnici da ga slušaju."},{"v":2,"t":"Stoga farizeji i pismoznanci mrmljahu: “Ovaj prima grešnike, i blaguje s njima.”"},{"v":3,"t":"Nato im Isus kaza ovu prispodobu:"},{"v":4,"t":"“Tko to od vas, ako ima sto ovaca pa izgubi jednu od njih, ne ostavi onih devedeset i devet u pustinji te pođe za izgubljenom dok je ne nađe?"},{"v":5,"t":"A kad je nađe, stavi je na ramena sav radostan"},{"v":6,"t":"pa došavši kući, sazove prijatelje i susjede i rekne im: 'Radujte se sa mnom! Nađoh ovcu svoju izgubljenu.'"},{"v":7,"t":"Kažem vam, tako će na nebu biti veća radost zbog jednog obraćena grešnika nego li zbog devedeset i devet pravednika kojima ne treba obraćenja.”"},{"v":8,"t":"“Ili koja to žena, ima li deset drahma pa izgubi jednu drahmu, ne zapali svjetiljku, pomete kuću i brižljivo pretraži dok je ne nađe?"},{"v":9,"t":"A kad je nađe, pozove prijateljice i susjede pa će im: 'Radujte se sa mnom! Nađoh drahmu što je bijah izgubila.'"},{"v":10,"t":"Tako, kažem vam, biva radost pred anđelima Božjim zbog jednog obraćena grešnika.”"},{"v":11,"t":"I nastavi: “Čovjek neki imao dva sina."},{"v":12,"t":"Mlađi reče ocu: 'Oče, daj mi dio dobara koji mi pripada.' I razdijeli im imanje."},{"v":13,"t":"Nakon nekoliko dana mlađi sin pokupi sve, otputova u daleku zemlju i ondje potrati svoja dobra živeći razvratno.”"},{"v":14,"t":"“Kad sve potroši, nasta ljuta glad u onoj zemlji te on poče oskudijevati."},{"v":15,"t":"Ode i pribi se kod jednoga žitelja u onoj zemlji. On ga posla na svoja polja pasti svinje."},{"v":16,"t":"Želio se nasititi rogačima što su ih jele svinje, ali mu ih nitko nije davao.”"},{"v":17,"t":"“Došavši k sebi, reče: 'Koliki najamnici oca moga imaju kruha napretek, a ja ovdje umirem od gladi!"},{"v":18,"t":"Ustat ću, poći svomu ocu i reći mu: 'Oče, sagriješih protiv Neba i pred tobom!"},{"v":19,"t":"Nisam više dostojan zvati se sinom tvojim. Primi me kao jednog od svojih najamnika.'”"},{"v":20,"t":"“Usta i pođe svom ocu. Dok je još bio daleko, njegov ga otac ugleda, ganu se, potrča, pade mu oko vrata i izljubi ga."},{"v":21,"t":"A sin će mu: 'Oče! Sagriješih protiv Neba i pred tobom! Nisam više dostojan zvati se sinom tvojim.'"},{"v":22,"t":"A otac reče slugama: 'Brzo iznesite haljinu najljepšu i obucite ga! Stavite mu prsten na ruku i obuću na noge!"},{"v":23,"t":"Tele ugojeno dovedite i zakoljite, pa da se pogostimo i proveselimo"},{"v":24,"t":"jer sin mi ovaj bijaše mrtav i oživje, izgubljen bijaše i nađe se!' I stadoše se veseliti.”"},{"v":25,"t":"“A stariji mu sin bijaše u polju. Kad se na povratku približio kući, začu svirku i igru"},{"v":26,"t":"pa dozva jednoga slugu da se raspita što je to."},{"v":27,"t":"A ovaj će mu: 'Došao tvoj brat pa otac tvoj zakla tele ugojeno što sina zdrava dočeka.'"},{"v":28,"t":"A on se rasrdi i ne htjede ući. Otac tada iziđe i stane ga nagovarati."},{"v":29,"t":"A on će ocu: 'Evo toliko ti godina služim i nikada ne prestupih tvoju zapovijed, a nikad mi ni jareta nisi dao da se s prijateljima proveselim."},{"v":30,"t":"A kada dođe ovaj sin tvoj koji s bludnicama proždrije tvoje imanje, ti mu zakla ugojeno tele.'"},{"v":31,"t":"Nato će mu otac: 'Sinko, ti si uvijek sa mnom i sve moje - tvoje je."},{"v":32,"t":"No trebalo se veseliti i radovati jer ovaj brat tvoj bijaše mrtav i oživje, izgubljen i nađe se!'”"}]},"16":{"fa":[{"v":1,"t":"و به شاگردان خود نیز گفت: «شخصی دولتمند را ناظری بود که از او نزد وی شکایت بردند که اموال او را تلف می‌کرد."},{"v":2,"t":"پس او را طلب نموده، وی را گفت، این چیست که درباره تو شنیده‌ام؟ حساب نظارت خود را باز بده زیرا ممکن نیست که بعد از این نظارت کنی."},{"v":3,"t":"ناظر با خود گفت چکنم؟ زیرا مولایم نظارت رااز من می‌گیرد. طاقت زمین‌کندن ندارم و از گدایی نیز عار دارم."},{"v":4,"t":"دانستم چکنم تا وقتی که از نظارت معزول شوم، مرا به خانه خود بپذیرند."},{"v":5,"t":"پس هریکی از بدهکاران آقای خود را طلبیده، به یکی گفت آقایم از تو چند طلب دارد؟"},{"v":6,"t":"گفت صدرطل روغن. بدو گفت سیاهه خود را بگیر ونشسته پنجاه رطل بزودی بنویس."},{"v":7,"t":"باز دیگری را گفت از تو چقدر طلب دارد؟ گفت صد کیل گندم. وی را گفت سیاهه خود را بگیر و هشتادبنویس."},{"v":8,"t":"«پس آقایش، ناظر خائن را آفرین گفت، زیراعاقلانه کار کرد. زیرا ابنای این جهان در طبقه خویش از ابنای نور عاقل تر هستند."},{"v":9,"t":"و من شمارا می‌گویم دوستان از مال بی‌انصافی برای خودپیدا کنید تا چون فانی گردید شما را به خیمه های جاودانی بپذیرند."},{"v":10,"t":"آنکه در اندک امین باشد درامر بزرگ نیز امین بود و آنکه در قلیل خائن بود در کثیر هم خائن باشد."},{"v":11,"t":"و هرگاه در مال بی‌انصافی امین نبودید، کیست که مال حقیقی را به شمابسپارد؟"},{"v":12,"t":"و اگر در مال دیگری دیانت نکردید، کیست که مال خاص شما را به شما دهد؟"},{"v":13,"t":"هیچ خادم نمی تواند دو آقا را خدمت کند. زیرا یا از یکی نفرت می‌کند و با دیگری محبت، یا با یکی می‌پیوندد و دیگری را حقیر می‌شمارد. خدا و مامونا را نمی توانید خدمت نمایید."},{"v":14,"t":"و فریسیانی که زر دوست بودند همه این سخنان را شنیده، او را استهزا نمودند."},{"v":15,"t":"به ایشان گفت، شما هستید که خود را پیش مردم عادل می‌نمایید، لیکن خدا عارف دلهای شماست. زیرا که آنچه نزد انسان مرغوب است، نزد خدا مکروه است."},{"v":16,"t":"تورات و انبیا تا به یحیی بود و از آن وقت بشارت به ملکوت خدا داده می‌شود و هر کس بجد و جهد داخل آن می‌گردد."},{"v":17,"t":"لیکن آسانتر است که آسمان و زمین زایل شود، از آنکه یک نقطه از تورات ساقط گردد."},{"v":18,"t":"هر‌که زن خود را طلاق دهد و دیگری را نکاح کند زانی بود و هر‌که زن مطلقه مردی را به نکاح خویش درآورد، زنا کرده باشد."},{"v":19,"t":"شخصی دولتمند بود که ارغوان و کتان می‌پوشید و هر روزه در عیاشی با جلال بسرمی برد."},{"v":20,"t":"و فقیری مقروح بود ایلعازر نام که او رابر درگاه او می‌گذاشتند،"},{"v":21,"t":"و آرزو می‌داشت که از پاره هایی که از خوان آن دولتمند می‌ریخت، خود را سیر کند. بلکه سگان نیز آمده زبان برزخمهای او می‌مالیدند."},{"v":22,"t":"باری آن فقیر بمرد و فرشتگان، او را به آغوش ابراهیم بردند و آن دولتمند نیز مرد و او را دفن کردند."},{"v":23,"t":"پس چشمان خود را در عالم اموات گشوده، خود رادر عذاب یافت. و ابراهیم را از دور و ایلعازر را درآغوشش دید."},{"v":24,"t":"آنگاه به آواز بلند گفت، ای پدرمن ابراهیم، بر من ترحم فرما و ایلعازر را بفرست تا سر انگشت خود را به آب تر ساخته زبان مراخنک سازد، زیرا در این نار معذبم."},{"v":25,"t":"ابراهیم گفت‌ای فرزند به‌خاطر آور که تو در ایام زندگانی چیزهای نیکوی خود را یافتی و همچنین ایلعازرچیزهای بد را، لیکن او الحال در تسلی است و تودر عذاب."},{"v":26,"t":"و علاوه بر این در میان ما و شماورطه عظیمی است، چنانچه آنانی که می‌خواهنداز اینجا به نزد شما عبور کنند، نمی توانند و نه نشینندگان آنجا نزد ما توانند گذشت."},{"v":27,"t":"گفت‌ای پدر به تو التماس دارم که او را به خانه پدرم بفرستی."},{"v":28,"t":"زیرا که مرا پنج برادر است تا ایشان راآگاه سازد، مبادا ایشان نیز به این مکان عذاب بیایند."},{"v":29,"t":"ابراهیم وی را گفت موسی و انبیا رادارند سخن ایشان را بشنوند."},{"v":30,"t":"گفت نه‌ای پدرما ابراهیم، لیکن اگر کسی از مردگان نزد ایشان رود، توبه خواهند کرد."},{"v":31,"t":"وی را گفت هرگاه موسی و انبیا را نشنوند اگر کسی از مردگان نیزبرخیزد، هدایت نخواهند پذیرفت.»"}],"en":[{"v":1,"t":"He also said to his disciples, “There was a certain rich man who had a manager. An accusation was made to him that this man was wasting his possessions."},{"v":2,"t":"He called him, and said to him, ‘What is this that I hear about you? Give an accounting of your management, for you can no longer be manager.’"},{"v":3,"t":"“The manager said within himself, ‘What will I do, seeing that my lord is taking away the management position from me? I don’t have strength to dig. I am ashamed to beg."},{"v":4,"t":"I know what I will do, so that when I am removed from management, they may receive me into their houses.’"},{"v":5,"t":"Calling each one of his lord’s debtors to him, he said to the first, ‘How much do you owe to my lord?’"},{"v":6,"t":"He said, ‘A hundred batos of oil.’ He said to him, ‘Take your bill, and sit down quickly and write fifty.’"},{"v":7,"t":"Then he said to another, ‘How much do you owe?’ He said, ‘A hundred cors of wheat.’ He said to him, ‘Take your bill, and write eighty.’"},{"v":8,"t":"“His lord commended the dishonest manager because he had done wisely, for the children of this world are, in their own generation, wiser than the children of the light."},{"v":9,"t":"I tell you, make for yourselves friends by means of unrighteous mammon, so that when you fail, they may receive you into the eternal tents."},{"v":10,"t":"He who is faithful in a very little is faithful also in much. He who is dishonest in a very little is also dishonest in much."},{"v":11,"t":"If therefore you have not been faithful in the unrighteous mammon, who will commit to your trust the true riches?"},{"v":12,"t":"If you have not been faithful in that which is another’s, who will give you that which is your own?"},{"v":13,"t":"No servant can serve two masters, for either he will hate the one and love the other; or else he will hold to one and despise the other. You aren’t able to serve God and Mammon.”"},{"v":14,"t":"The Pharisees, who were lovers of money, also heard all these things, and they scoffed at him."},{"v":15,"t":"He said to them, “You are those who justify yourselves in the sight of men, but God knows your hearts. For that which is exalted among men is an abomination in the sight of God."},{"v":16,"t":"“The law and the prophets were until John. From that time the Good News of God’s Kingdom is preached, and everyone is forcing his way into it."},{"v":17,"t":"But it is easier for heaven and earth to pass away than for one tiny stroke of a pen in the law to fall."},{"v":18,"t":"“Everyone who divorces his wife and marries another commits adultery. He who marries one who is divorced from a husband commits adultery."},{"v":19,"t":"“Now there was a certain rich man, and he was clothed in purple and fine linen, living in luxury every day."},{"v":20,"t":"A certain beggar, named Lazarus, was taken to his gate, full of sores,"},{"v":21,"t":"and desiring to be fed with the crumbs that fell from the rich man’s table. Yes, even the dogs came and licked his sores."},{"v":22,"t":"The beggar died, and he was carried away by the angels to Abraham’s bosom. The rich man also died and was buried."},{"v":23,"t":"In Hades, he lifted up his eyes, being in torment, and saw Abraham far off, and Lazarus at his bosom."},{"v":24,"t":"He cried and said, ‘Father Abraham, have mercy on me, and send Lazarus, that he may dip the tip of his finger in water and cool my tongue! For I am in anguish in this flame.’"},{"v":25,"t":"“But Abraham said, ‘Son, remember that you, in your lifetime, received your good things, and Lazarus, in the same way, bad things. But here he is now comforted and you are in anguish."},{"v":26,"t":"Besides all this, between us and you there is a great gulf fixed, that those who want to pass from here to you are not able, and that no one may cross over from there to us.’"},{"v":27,"t":"“He said, ‘I ask you therefore, father, that you would send him to my father’s house—"},{"v":28,"t":"for I have five brothers—that he may testify to them, so they won’t also come into this place of torment.’"},{"v":29,"t":"“But Abraham said to him, ‘They have Moses and the prophets. Let them listen to them.’"},{"v":30,"t":"“He said, ‘No, father Abraham, but if one goes to them from the dead, they will repent.’"},{"v":31,"t":"“He said to him, ‘If they don’t listen to Moses and the prophets, neither will they be persuaded if one rises from the dead.’”"}],"hr":[{"v":1,"t":"Govoraše i svojim učenicima: “Bijaše neki bogat čovjek koji je imao upravitelja."},{"v":2,"t":"Ovaj je bio optužen pred njim kao da mu rasipa imanje. On ga pozva pa mu reče: 'Što to čujem o tebi? Položi račun o svom upravljanju jer više ne možeš biti upravitelj!'"},{"v":3,"t":"Nato upravitelj reče u sebi: 'Što da učinim kad mi gospodar moj oduzima upravu? Kopati? Nemam snage. Prositi? Stidim se."},{"v":4,"t":"Znam što ću da me prime u svoje kuće kad budem maknut s uprave.'”"},{"v":5,"t":"“I pozva dužnike svoga gospodara, jednog po jednog. Upita prvoga: 'Koliko duguješ gospodaru mojemu?' On reče: 'Sto bata ulja.'"},{"v":6,"t":"A on će mu: 'Uzmi svoju zadužnicu, sjedni brzo, napiši pedeset.'"},{"v":7,"t":"Zatim reče drugomu: 'A ti, koliko ti duguješ?' On odgovori: 'Sto kora pšenice.' Kaže mu: 'Uzmi svoju zadužnicu i napiši osamdeset.'”"},{"v":8,"t":"“I pohvali gospodar nepoštenog upravitelja što snalažljivo postupi jer sinovi su ovoga svijeta snalažljiviji prema svojima od sinova svjetlosti.”"},{"v":9,"t":"“I ja vama kažem: napravite sebi prijatelje od nepoštena bogatstva pa kad ga nestane da vas prime u vječne šatore.”"},{"v":10,"t":"“Tko je vjeran u najmanjem, i u najvećem je vjeran; a tko je u najmanjem nepošten, i u najvećem je nepošten."},{"v":11,"t":"Ako dakle ne bijaste vjerni u nepoštenom bogatstvu, tko li će vam istinsko povjeriti?"},{"v":12,"t":"I ako u tuđem ne bijaste vjerni, tko li će vam vaše dati?”"},{"v":13,"t":"“Nijedan sluga ne može služiti dvojici gospodara. Ili će jednoga mrziti, a drugoga ljubiti; ili će uz jednoga prianjati, a drugoga prezirati. Ne možete služiti Bogu i bogatstvu.”"},{"v":14,"t":"Sve su to slušali farizeji, srebroljupci, i rugali mu se."},{"v":15,"t":"On im reče: “Vi se pravite pravedni pred ljudima, ali zna Bog srca vaša. Jer što je ljudima uzvišeno, odvratnost je pred Bogom.”"},{"v":16,"t":"“Zakon i Proroci do Ivana su, a otada se navješćuje kraljevstvo Božje i svatko se u nj silom probija."},{"v":17,"t":"Lakše će nebo i zemlja proći, negoli propasti i jedan potezić Zakona.”"},{"v":18,"t":"“Tko god otpusti svoju ženu pa se oženi drugom, čini preljub. I tko se god oženi otpuštenom, čini preljub.”"},{"v":19,"t":"“Bijaše neki bogataš. Odijevao se u grimiz i tanani lan i danomice se sjajno gostio."},{"v":20,"t":"A neki siromah, imenom Lazar, ležao je sav u čirevima pred njegovim vratima"},{"v":21,"t":"i priželjkivao nasititi se onim što je padalo s bogataševa stola. Čak su i psi dolazili i lizali mu čireve.”"},{"v":22,"t":"“Kad umrije siromah, odnesoše ga anđeli u krilo Abrahamovo. Umrije i bogataš te bude pokopan."},{"v":23,"t":"Tada u teškim mukama u paklu, podiže svoje oči te izdaleka ugleda Abrahama i u krilu mu Lazara"},{"v":24,"t":"pa zavapi: 'Oče Abrahame, smiluj mi se i pošalji Lazara da umoči vršak svoga prsta u vodu i rashladi mi jezik jer se strašno mučim u ovom plamenu.'"},{"v":25,"t":"Reče nato Abraham: 'Sinko! Sjeti se da si za života primio dobra svoja, a tako i Lazar zla. Sada se on ovdje tješi, a ti se mučiš."},{"v":26,"t":"K tome između nas i vas zjapi provalija golema te koji bi i htjeli prijeći odavde k vama, ne mogu, a ni odatle k nama prijelaza nema.'”"},{"v":27,"t":"“Nato će bogataš: 'Molim te onda, oče, pošalji Lazara u kuću oca moga."},{"v":28,"t":"Imam petero braće pa neka im posvjedoči da i oni ne dođu u ovo mjesto muka.'"},{"v":29,"t":"Kaže Abraham: 'Imaju Mojsija i Proroke! Njih neka poslušaju!'"},{"v":30,"t":"A on će: 'O ne, oče Abrahame! Nego dođe li tko od mrtvih k njima, obratit će se.'"},{"v":31,"t":"Reče mu: 'Ako ne slušaju Mojsija i Proroka, neće povjerovati sve da i od mrtvih tko ustane.'”"}]},"17":{"fa":[{"v":1,"t":"و شاگردان خود را گفت: «لابد است ازوقوع لغزشها، لیکن وای بر آن کسی‌که باعث آنها شود."},{"v":2,"t":"او را بهتر می‌بود که سنگ آسیایی بر گردنش آویخته شود و در دریا افکنده شود از اینکه یکی از این کودکان را لغزش دهد."},{"v":3,"t":"احتراز کنید و اگر برادرت به تو خطا ورزد او راتنبیه کن و اگر توبه کند او را ببخش."},{"v":4,"t":"و هرگاه درروزی هفت کرت به تو گناه کند و در روزی هفت مرتبه، برگشته به تو گوید توبه می‌کنم، او راببخش.»"},{"v":5,"t":"آنگاه رسولان به خداوند گفتند: «ایمان ما رازیاد کن.»"},{"v":6,"t":"خداوند گفت: «اگر ایمان به قدر دانه خردلی می‌داشتید، به این درخت افراغ می‌گفتیدکه کنده شده در دریا نشانده شود اطاعت شمامی کرد."},{"v":7,"t":"«اما کیست از شماکه غلامش به شخم کردن یا شبانی مشغول شود و وقتی که از صحرا آید به وی گوید، بزودی بیا و بنشین."},{"v":8,"t":"بلکه آیا بدونمی گوید چیزی درست کن تا شام بخورم و کمرخود را بسته مرا خدمت کن تا بخورم و بنوشم وبعد از آن تو بخور و بیاشام؟"},{"v":9,"t":"آیا از آن غلام منت می‌کشد از آنکه حکمهای او را به‌جا آورد؟ گمان ندارم."},{"v":10,"t":"همچنین شما نیز چون به هر چیزی که مامور شده‌اید عمل کردید، گویید که غلامان بی‌منفعت هستیم زیرا که آنچه بر ما واجب بود به‌جا آوردیم.»"},{"v":11,"t":"و هنگامی که سفر به سوی اورشلیم می‌کرداز میانه سامره و جلیل می‌رفت."},{"v":12,"t":"و چون به قریه‌ای داخل می‌شد ناگاه ده شخص ابرص به استقبال او آمدند و از دور ایستاده،"},{"v":13,"t":"به آواز بلندگفتند: «ای عیسی خداوند بر ما ترحم فرما.»"},{"v":14,"t":"اوبه ایشان نظر کرده گفت: «بروید و خود را به کاهن بنمایید.» ایشان چون می‌رفتند، طاهر گشتند."},{"v":15,"t":"و یکی از ایشان چون دید که شفا یافته است، برگشته به صدای بلند خدا را تمجید می‌کرد."},{"v":16,"t":"وپیش قدم او به روی در‌افتاده وی را شکر کرد. و اواز اهل سامره بود."},{"v":17,"t":"عیسی ملتفت شده گفت «آیا ده نفر طاهر نشدند، پس آن نه کجا شدند؟"},{"v":18,"t":"آیا هیچ‌کس یافت نمی شود که برگشته خدا راتمجید کند جز این غریب؟»"},{"v":19,"t":"و بدو گفت: «برخاسته برو که ایمانت تو را نجات داده است.»"},{"v":20,"t":"و چون فریسیان از او پرسیدند که ملکوت خدا کی می‌آید، او در جواب ایشان گفت: «ملکوت خدا با مراقبت نمی آید."},{"v":21,"t":"و نخواهندگفت که در فلان یا فلان جاست. زیرا اینک ملکوت خدا در میان شما است.»"},{"v":22,"t":"و به شاگردان خود گفت: «ایامی می‌آید که آرزو خواهید داشت که روزی از روزهای پسر انسان را بینید ونخواهید دید."},{"v":23,"t":"و به شما خواهند گفت، اینک در فلان یا فلان جاست، مروید و تعاقب آن مکنید."},{"v":24,"t":"زیرا چون برق که از یک جانب زیرآسمان لامع شده تا جانب دیگر زیر آسمان درخشان می‌شود، پسر انسان در یوم خودهمچنین خواهد بود."},{"v":25,"t":"لیکن اول لازم است که اوزحمات بسیار بیند و از این فرقه مطرود شود."},{"v":26,"t":"و چنانکه در ایام نوح واقع شد، همانطوردر زمان پسر انسان نیز خواهد بود،"},{"v":27,"t":"که می‌خوردند و می‌نوشیدند و زن و شوهرمی گرفتند تا روزی که چون نوح داخل کشتی شد، طوفان آمده همه را هلاک ساخت."},{"v":28,"t":"وهمچنان‌که در ایام لوط شد که به خوردن وآشامیدن و خرید و فروش و زراعت و عمارت مشغول می‌بودند،"},{"v":29,"t":"تا روزی که چون لوط ازسدوم بیرون آمد، آتش و گوگرد از آسمان باریدو همه را هلاک ساخت."},{"v":30,"t":"بر همین منوال خواهدبود در روزی که پسر انسان ظاهر شود."},{"v":31,"t":"در آن روز هر‌که بر پشت بام باشد و اسباب او در خانه نزول نکند تا آنها را بردارد و کسی‌که در صحراباشد همچنین برنگردد."},{"v":32,"t":"زن لوط را بیاد آورید."},{"v":33,"t":"هر‌که خواهد جان خود را برهاند آن را هلاک خواهد کرد و هر‌که آن را هلاک کند آن را زنده نگاه خواهد داشت."},{"v":34,"t":"به شما می‌گویم در آن شب دو نفر بر یک تخت خواهند بود، یکی برداشته و دیگری واگذارده خواهد شد."},{"v":35,"t":"و دوزن که در یک جا دستاس کنند، یکی برداشته ودیگری واگذارده خواهد شد."},{"v":36,"t":"و دونفر که درمزرعه باشند، یکی برداشته و دیگری واگذارده خواهد شد.»"},{"v":37,"t":"در جواب وی گفتند: «کجا‌ای خداوند.» گفت: «در هر جایی که لاش باشد درآنجا کرکسان جمع خواهند شد.»"}],"en":[{"v":1,"t":"He said to the disciples, “It is impossible that no occasions of stumbling should come, but woe to him through whom they come!"},{"v":2,"t":"It would be better for him if a millstone were hung around his neck, and he were thrown into the sea, rather than that he should cause one of these little ones to stumble."},{"v":3,"t":"Be careful. If your brother sins against you, rebuke him. If he repents, forgive him."},{"v":4,"t":"If he sins against you seven times in the day, and seven times returns, saying, ‘I repent,’ you shall forgive him.”"},{"v":5,"t":"The apostles said to the Lord, “Increase our faith.”"},{"v":6,"t":"The Lord said, “If you had faith like a grain of mustard seed, you would tell this sycamore tree, ‘Be uprooted and be planted in the sea,’ and it would obey you."},{"v":7,"t":"But who is there among you, having a servant plowing or keeping sheep, that will say when he comes in from the field, ‘Come immediately and sit down at the table’?"},{"v":8,"t":"Wouldn’t he rather tell him, ‘Prepare my supper, clothe yourself properly, and serve me while I eat and drink. Afterward you shall eat and drink’?"},{"v":9,"t":"Does he thank that servant because he did the things that were commanded? I think not."},{"v":10,"t":"Even so you also, when you have done all the things that are commanded you, say, ‘We are unworthy servants. We have done our duty.’”"},{"v":11,"t":"As he was on his way to Jerusalem, he was passing along the borders of Samaria and Galilee."},{"v":12,"t":"As he entered into a certain village, ten men who were lepers met him, who stood at a distance."},{"v":13,"t":"They lifted up their voices, saying, “Jesus, Master, have mercy on us!”"},{"v":14,"t":"When he saw them, he said to them, “Go and show yourselves to the priests.” As they went, they were cleansed."},{"v":15,"t":"One of them, when he saw that he was healed, turned back, glorifying God with a loud voice."},{"v":16,"t":"He fell on his face at Jesus’ feet, giving him thanks; and he was a Samaritan."},{"v":17,"t":"Jesus answered, “Weren’t the ten cleansed? But where are the nine?"},{"v":18,"t":"Were there none found who returned to give glory to God, except this foreigner?”"},{"v":19,"t":"Then he said to him, “Get up, and go your way. Your faith has healed you.”"},{"v":20,"t":"Being asked by the Pharisees when God’s Kingdom would come, he answered them, “God’s Kingdom doesn’t come with observation;"},{"v":21,"t":"neither will they say, ‘Look, here!’ or, ‘Look, there!’ for behold, God’s Kingdom is within you.”"},{"v":22,"t":"He said to the disciples, “The days will come when you will desire to see one of the days of the Son of Man, and you will not see it."},{"v":23,"t":"They will tell you, ‘Look, here!’ or ‘Look, there!’ Don’t go away or follow after them,"},{"v":24,"t":"for as the lightning, when it flashes out of one part under the sky, shines to another part under the sky, so will the Son of Man be in his day."},{"v":25,"t":"But first, he must suffer many things and be rejected by this generation."},{"v":26,"t":"As it was in the days of Noah, even so it will also be in the days of the Son of Man."},{"v":27,"t":"They ate, they drank, they married, and they were given in marriage until the day that Noah entered into the ship, and the flood came and destroyed them all."},{"v":28,"t":"Likewise, even as it was in the days of Lot: they ate, they drank, they bought, they sold, they planted, they built;"},{"v":29,"t":"but in the day that Lot went out from Sodom, it rained fire and sulfur from the sky and destroyed them all."},{"v":30,"t":"It will be the same way in the day that the Son of Man is revealed."},{"v":31,"t":"In that day, he who will be on the housetop and his goods in the house, let him not go down to take them away. Let him who is in the field likewise not turn back."},{"v":32,"t":"Remember Lot’s wife!"},{"v":33,"t":"Whoever seeks to save his life loses it, but whoever loses his life preserves it."},{"v":34,"t":"I tell you, in that night there will be two people in one bed. One will be taken and the other will be left."},{"v":35,"t":"There will be two grinding grain together. One will be taken and the other will be left.”"},{"v":37,"t":"They, answering, asked him, “Where, Lord?” He said to them, “Where the body is, there the vultures will also be gathered together.”"}],"hr":[{"v":1,"t":"I reče svojim učenicima: “Nije moguće da ne dođu sablazni, no jao onome po kom dolaze;"},{"v":2,"t":"je li s mlinskim kamenom o vratu strovaljen u more, korisnije mu je, nego da sablazni jednoga od ovih malenih."},{"v":3,"t":"Čuvajte se!” “Pogriješi li tvoj brat, prekori ga; ako se obrati, oprosti mu."},{"v":4,"t":"Pa ako se sedam puta na dan ogriješi o tebe i sedam se puta obrati tebi govoreći: 'Žao mi je!', oprosti mu.”"},{"v":5,"t":"Apostoli zamole Gospodina: “Umnoži nam vjeru!”"},{"v":6,"t":"Gospodin im odvrati: “Da imate vjere koliko je zrno gorušičino, rekli biste ovom dudu: 'Iščupaj se s korijenom i presadi se u more!' I on bi vas poslušao.”"},{"v":7,"t":"“Tko će to od vas reći sluzi svomu, oraču ili pastiru, koji se vrati s polja: 'Dođi brzo i sjedni za stol?'"},{"v":8,"t":"Neće li mu naprotiv reći: 'Pripravi što ću večerati pa se pripaši i poslužuj mi dok jedem i pijem; potom ćeš ti jesti i piti?'"},{"v":9,"t":"Zar duguje zahvalnost sluzi jer je izvršio što mu je naređeno?"},{"v":10,"t":"Tako i vi: kad izvršite sve što vam je naređeno, recite: 'Sluge smo beskorisne! Učinismo što smo bili dužni učiniti!'”"},{"v":11,"t":"Dok je tako putovao u Jeruzalem, prolazio je između Samarije i Galileje."},{"v":12,"t":"Kad je ulazio u neko selo, eto mu u susret deset gubavaca. Zaustave se podaleko"},{"v":13,"t":"i zavape: “Isuse, Učitelju, smiluj nam se!”"},{"v":14,"t":"Kad ih Isus ugleda, reče im: “Idite, pokažite se svećenicima!” I dok su išli, očistiše se."},{"v":15,"t":"Jedan od njih vidjevši da je ozdravio, vrati se slaveći Boga u sav glas."},{"v":16,"t":"Baci se ničice k Isusovim nogama zahvaljujući mu. A to bijaše neki Samarijanac."},{"v":17,"t":"Nato Isus primijeti: “Zar se ne očistiše desetorica?"},{"v":18,"t":"A gdje su ona devetorica? Ne nađe li se nijedan koji bi se vratio i podao slavu Bogu, osim ovoga tuđinca?”"},{"v":19,"t":"A njemu reče: “Ustani! Idi! Tvoja te vjera spasila!”"},{"v":20,"t":"Upitaju ga farizeji: “Kad će doći kraljevstvo Božje?” Odgovori im: “Kraljevstvo Božje ne dolazi primjetljivo."},{"v":21,"t":"Niti će se moći kazati: 'Evo ga ovdje!' ili: 'Eno ga ondje!' Ta evo - kraljevstvo je Božje među vama!”"},{"v":22,"t":"Zatim reče učenicima: “Doći će dani kad ćete zaželjeti vidjeti i jedan dan Sina Čovječjega, ali ga nećete vidjeti."},{"v":23,"t":"Govorit će vam: 'Eno ga ondje, evo ovdje!' Ne odlazite i ne pomamite se!"},{"v":24,"t":"Jer kao što munja sijevne na jednom kraju obzorja i odbljesne na drugom, tako će biti i sa Sinom Čovječjim u Dan njegov."},{"v":25,"t":"No prije treba da on mnogo pretrpi i da ga ovaj naraštaj odbaci.”"},{"v":26,"t":"“I kao što bijaše u dane Noine, tako će biti i u dane Sina Čovječjega:"},{"v":27,"t":"jeli su, pili, ženili se i udavali do dana kad Noa uđe u korablju. I dođe potop i sve uništi."},{"v":28,"t":"Slično kao što bijaše u dane Lotove: jeli su, pili, kupovali, prodavali, sadili, gradili."},{"v":29,"t":"A onog dana kad Lot iziđe iz Sodome, zapljušti s neba oganj i sumpor i sve uništi."},{"v":30,"t":"Tako će isto biti u dan kad se Sin Čovječji objavi.”"},{"v":31,"t":"“U onaj dan tko bude na krovu, a stvari mu u kući, neka ne siđe da ih uzme."},{"v":32,"t":"I tko bude u polju, neka se ne okreće natrag. Sjetite se žene Lotove!"},{"v":33,"t":"Tko god bude nastojao život svoj sačuvati, izgubit će ga; a tko ga izgubi, živa će ga sačuvati.”"},{"v":34,"t":"“Kažem vam, one će noći biti dvojica u jednoj postelji: jedan će se uzeti, drugi ostaviti."},{"v":35,"t":"Dvije će mljeti zajedno: jedna će se uzeti, druga ostaviti.”"},{"v":36,"t":"#"},{"v":37,"t":"Upitaše ga na to: “Gdje to, Gospodine?” A on im reče: “Gdje bude trupla, ondje će se okupljati i orlovi.”"}]},"18":{"fa":[{"v":1,"t":"و برای ایشان نیز مثلی آورد در اینکه می باید همیشه دعا کرد و کاهلی نورزید."},{"v":2,"t":"پس گفت که «در شهری داوری بود که نه ترس از خدا و نه باکی از انسان می‌داشت."},{"v":3,"t":"ودر همان شهر بیوه‌زنی بود که پیش وی آمده می‌گفت، داد مرا از دشمنم بگیر."},{"v":4,"t":"و تا مدتی به وی اعتناننمود ولکن بعد از آن با خود گفت هرچند از خدا نمی ترسم و از مردم باکی ندارم،"},{"v":5,"t":"لیکن چون این بیوه‌زن مرا زحمت می‌دهد، به داد او می‌رسم، مبادا پیوسته آمده مرا به رنج آورد."},{"v":6,"t":"خداوند گفت بشنوید که این داوربی انصاف چه می‌گوید؟"},{"v":7,"t":"و آیا خدا برگزیدگان خود را که شبانه‌روز بدو استغاثه می‌کنند، دادرسی نخواهد کرد، اگرچه برای ایشان دیرغضب باشد؟"},{"v":8,"t":"به شما می‌گویم که به زودی دادرسی ایشان را خواهد کرد. لیکن چون پسرانسان آید، آیا ایمان را بر زمین خواهدیافت؟"},{"v":9,"t":"و این مثل را آورد برای بعضی که بر خوداعتماد می‌داشتند که عادل بودند و دیگران راحقیر می‌شمردند."},{"v":10,"t":"که «دو نفر یکی فریسی ودیگری باجگیر به هیکل رفتند تا عبادت کنند."},{"v":11,"t":"آن فریسی ایستاده بدینطور با خود دعا کرد که خدایا تو را شکر می‌کنم که مثل سایر مردم حریص و ظالم و زناکار نیستم و نه مثل این باجگیر،"},{"v":12,"t":"هر هفته دو مرتبه روزه می‌دارم و ازآنچه پیدا می‌کنم ده‌یک می‌دهم."},{"v":13,"t":"اما آن باجگیر دور ایستاده نخواست چشمان خود را به سوی آسمان بلند کند بلکه به سینه خود زده گفت، خدایا بر من گناهکار ترحم فرما."},{"v":14,"t":"به شمامی گویم که این شخص، عادل کرده شده به خانه خود رفت به خلاف آن دیگر، زیرا هر‌که خود رابرافرازد، پست گردد و هرکس خویشتن را فروتن سازد، سرافرازی یابد.»"},{"v":15,"t":"پس اطفال را نیز نزد وی آوردند تا دست برایشان گذارد. اما شاگردانش چون دیدند، ایشان رانهیب دادند."},{"v":16,"t":"ولی عیسی ایشان را خوانده، گفت: «بچه‌ها را واگذارید تا نزد من آیند و ایشان را ممانعت مکنید، زیرا ملکوت خدا برای مثل اینها است."},{"v":17,"t":"هرآینه به شما می‌گویم هر‌که ملکوت خدا را مثل طفل نپذیرد داخل آن نگردد.»"},{"v":18,"t":"و یکی از روسا از وی سوال نموده، گفت: «ای استاد نیکو چه کنم تا حیات جاودانی راوارث گردم؟»"},{"v":19,"t":"عیسی وی را گفت: «از بهر‌چه مرا نیکو می‌گویی و حال آنکه هیچ‌کس نیکونیست جز یکی که خدا باشد."},{"v":20,"t":"احکام رامی دانی زنا مکن، قتل مکن، دزدی منما، شهادت دروغ مده و پدر و مادر خود را محترم دار.»"},{"v":21,"t":"گفت: «جمیع اینها را از طفولیت خود نگاه داشته‌ام.»"},{"v":22,"t":"عیسی چون این را شنید بدو گفت: «هنوز تو را یک چیز باقی است. آنچه داری بفروش و به فقرا بده که در آسمان گنجی خواهی داشت، پس آمده مرا متابعت کن.»"},{"v":23,"t":"چون این راشنید محزون گشت، زیرا که دولت فراوان داشت."},{"v":24,"t":"اما عیسی چون او را محزون دید گفت: «چه دشوار است که دولتمندان داخل ملکوت خداشوند."},{"v":25,"t":"زیرا گذشتن شتر از سوراخ سوزن آسانتر است از دخول دولتمندی در ملکوت خدا.»"},{"v":26,"t":"اما شنوندگان گفتند: «پس که می‌تواندنجات یابد؟»"},{"v":27,"t":"او گفت: «آنچه نزد مردم محال است، نزد خدا ممکن است.»"},{"v":28,"t":"پطرس گفت: «اینک ما همه‌چیز را ترک کرده پیروی تو می‌کنیم.»"},{"v":29,"t":"به ایشان گفت: «هرآینه به شما می‌گویم، کسی نیست که خانه یاوالدین یا زن یا برادران یا اولاد را بجهت ملکوت خدا ترک کند،"},{"v":30,"t":"جز اینکه در این عالم چند برابربیابد و در عالم آینده حیات جاودانی را.»"},{"v":31,"t":"پس آن دوازده را برداشته، به ایشان گفت: «اینک به اورشلیم می‌رویم و آنچه به زبان انبیادرباره پسر انسان نوشته شده است، به انجام خواهد رسید."},{"v":32,"t":"زیرا که او را به امت‌ها تسلیم می‌کنند و استهزا و بی‌حرمتی کرده آب دهان بروی انداخته"},{"v":33,"t":"و تازیانه زده او را خواهند کشت ودر روز سوم خواهد برخاست.»"},{"v":34,"t":"اما ایشان چیزی از این امور نفهمیدند و این سخن از ایشان مخفی داشته شد و آنچه می‌گفت، درک نکردند."},{"v":35,"t":"و چون نزدیک اریحا رسید، کوری بجهت گدایی بر سر راه نشسته بود."},{"v":36,"t":"و چون صدای گروهی را که می‌گذشتند شنید، پرسید چه چیزاست؟"},{"v":37,"t":"گفتندش عیسی ناصری در گذر است."},{"v":38,"t":"در حال فریاد برآورده گفت: «ای عیسی، ای پسر داود، بر من ترحم فرما.»"},{"v":39,"t":"و هرچند آنانی که پیش می‌رفتند او را نهیب می‌دادند تا خاموش شود، او بلندتر فریاد می‌زد که پسر داودا بر من ترحم فرما."},{"v":40,"t":"آنگاه عیسی ایستاده فرمود تا او رانزد وی بیاورند. و چون نزدیک شد از وی پرسیده،"},{"v":41,"t":"گفت: «چه می‌خواهی برای توبکنم؟» عرض کرد: «ای خداوند، تا بینا شوم.»"},{"v":42,"t":"عیسی به وی گفت: «بینا شو که ایمانت تو راشفا داده است.»"},{"v":43,"t":"در ساعت بینایی یافته، خدا راتمجید‌کنان از عقب او افتاد و جمیع مردم چون این را دیدند، خدا را تسبیح خواندند."}],"en":[{"v":1,"t":"He also spoke a parable to them that they must always pray and not give up,"},{"v":2,"t":"saying, “There was a judge in a certain city who didn’t fear God and didn’t respect man."},{"v":3,"t":"A widow was in that city, and she often came to him, saying, ‘Defend me from my adversary!’"},{"v":4,"t":"He wouldn’t for a while; but afterward he said to himself, ‘Though I neither fear God nor respect man,"},{"v":5,"t":"yet because this widow bothers me, I will defend her, or else she will wear me out by her continual coming.’”"},{"v":6,"t":"The Lord said, “Listen to what the unrighteous judge says."},{"v":7,"t":"Won’t God avenge his chosen ones who are crying out to him day and night, and yet he exercises patience with them?"},{"v":8,"t":"I tell you that he will avenge them quickly. Nevertheless, when the Son of Man comes, will he find faith on the earth?”"},{"v":9,"t":"He also spoke this parable to certain people who were convinced of their own righteousness, and who despised all others:"},{"v":10,"t":"“Two men went up into the temple to pray; one was a Pharisee, and the other was a tax collector."},{"v":11,"t":"The Pharisee stood and prayed by himself like this: ‘God, I thank you that I am not like the rest of men: extortionists, unrighteous, adulterers, or even like this tax collector."},{"v":12,"t":"I fast twice a week. I give tithes of all that I get.’"},{"v":13,"t":"But the tax collector, standing far away, wouldn’t even lift up his eyes to heaven, but beat his chest, saying, ‘God, be merciful to me, a sinner!’"},{"v":14,"t":"I tell you, this man went down to his house justified rather than the other; for everyone who exalts himself will be humbled, but he who humbles himself will be exalted.”"},{"v":15,"t":"They were also bringing their babies to him, that he might touch them. But when the disciples saw it, they rebuked them."},{"v":16,"t":"Jesus summoned them, saying, “Allow the little children to come to me, and don’t hinder them, for God’s Kingdom belongs to such as these."},{"v":17,"t":"Most certainly, I tell you, whoever doesn’t receive God’s Kingdom like a little child, he will in no way enter into it.”"},{"v":18,"t":"A certain ruler asked him, saying, “Good Teacher, what shall I do to inherit eternal life?”"},{"v":19,"t":"Jesus asked him, “Why do you call me good? No one is good, except one: God."},{"v":20,"t":"You know the commandments: ‘Don’t commit adultery,’ ‘Don’t murder,’ ‘Don’t steal,’ ‘Don’t give false testimony,’ ‘Honor your father and your mother.’”"},{"v":21,"t":"He said, “I have observed all these things from my youth up.”"},{"v":22,"t":"When Jesus heard these things, he said to him, “You still lack one thing. Sell all that you have and distribute it to the poor. Then you will have treasure in heaven; then come, follow me.”"},{"v":23,"t":"But when he heard these things, he became very sad, for he was very rich."},{"v":24,"t":"Jesus, seeing that he became very sad, said, “How hard it is for those who have riches to enter into God’s Kingdom!"},{"v":25,"t":"For it is easier for a camel to enter in through a needle’s eye than for a rich man to enter into God’s Kingdom.”"},{"v":26,"t":"Those who heard it said, “Then who can be saved?”"},{"v":27,"t":"But he said, “The things which are impossible with men are possible with God.”"},{"v":28,"t":"Peter said, “Look, we have left everything and followed you.”"},{"v":29,"t":"He said to them, “Most certainly I tell you, there is no one who has left house, or wife, or brothers, or parents, or children, for God’s Kingdom’s sake,"},{"v":30,"t":"who will not receive many times more in this time, and in the world to come, eternal life.”"},{"v":31,"t":"He took the twelve aside and said to them, “Behold, we are going up to Jerusalem, and all the things that are written through the prophets concerning the Son of Man will be completed."},{"v":32,"t":"For he will be delivered up to the Gentiles, will be mocked, treated shamefully, and spit on."},{"v":33,"t":"They will scourge and kill him. On the third day, he will rise again.”"},{"v":34,"t":"They understood none of these things. This saying was hidden from them, and they didn’t understand the things that were said."},{"v":35,"t":"As he came near Jericho, a certain blind man sat by the road, begging."},{"v":36,"t":"Hearing a multitude going by, he asked what this meant."},{"v":37,"t":"They told him that Jesus of Nazareth was passing by."},{"v":38,"t":"He cried out, “Jesus, you son of David, have mercy on me!”"},{"v":39,"t":"Those who led the way rebuked him, that he should be quiet; but he cried out all the more, “You son of David, have mercy on me!”"},{"v":40,"t":"Standing still, Jesus commanded him to be brought to him. When he had come near, he asked him,"},{"v":41,"t":"“What do you want me to do?” He said, “Lord, that I may see again.”"},{"v":42,"t":"Jesus said to him, “Receive your sight. Your faith has healed you.”"},{"v":43,"t":"Immediately he received his sight and followed him, glorifying God. All the people, when they saw it, praised God."}],"hr":[{"v":1,"t":"Kaza im i prispodobu kako valja svagda moliti i nikada ne sustati:"},{"v":2,"t":"“U nekom gradu bio sudac. Boga se nije bojao, za ljude nije mario."},{"v":3,"t":"U tom gradu bijaše i neka udovica. Dolazila k njemu i molila: 'Obrani me od mog tužitelja!'"},{"v":4,"t":"No on ne htjede zadugo. Napokon reče u sebi: 'Iako se Boga ne bojim nit za ljude marim, ipak,"},{"v":5,"t":"jer mi udovica ova dodijava, obranit ću je da vječno ne dolazi mučiti me.'”"},{"v":6,"t":"Nato reče Gospodin: “Čujte što govori nepravedni sudac!"},{"v":7,"t":"Neće li onda Bog obraniti svoje izabrane koji dan i noć vape k njemu sve ako i odgađa stvar njihovu?"},{"v":8,"t":"Kažem vam, ustat će žurno na njihovu obranu. Ali kad Sin Čovječji dođe, hoće li naći vjere na zemlji?”"},{"v":9,"t":"Nekima pak koji se pouzdavahu u sebe da su pravednici, a druge potcjenjivahu, reče zatim ovu prispodobu:"},{"v":10,"t":"“Dva čovjeka uziđoše u Hram pomoliti se: jedan farizej, drugi carinik."},{"v":11,"t":"Farizej se uspravan ovako u sebi molio: 'Bože, hvala ti što nisam kao ostali ljudi: grabežljivci, nepravednici, preljubnici ili - kao ovaj carinik.'"},{"v":12,"t":"Postim dvaput u tjednu, dajem desetinu od svega što steknem.'"},{"v":13,"t":"A carinik, stojeći izdaleka, ne usudi se ni očiju podignuti k nebu, nego se udaraše u prsa govoreći: 'Bože milostiv budi meni grešniku!'"},{"v":14,"t":"Kažem vam: ovaj siđe opravdan kući svojoj, a ne onaj! Svaki koji se uzvisuje, bit će ponižen; a koji se ponizuje, bit će uzvišen.”"},{"v":15,"t":"A donosili mu i dojenčad da ih se dotakne. Vidjevši to, učenici im branili."},{"v":16,"t":"A Isus ih dozva i reče: “Pustite dječicu neka dolaze k meni i ne priječite im jer takvih je kraljevstvo Božje.”"},{"v":17,"t":"“Zaista, kažem vam, tko ne primi kraljevstva Božjega kao dijete, ne, u nj neće ući.”"},{"v":18,"t":"I upita ga neki uglednik: “Učitelju dobri, što mi je činiti da baštinim život vječni?”"},{"v":19,"t":"Reče mu Isus: “Što me zoveš dobrim? Nitko nije dobar, doli Bog jedini."},{"v":20,"t":"Zapovijedi znaš: Ne čini preljuba! Ne ubij! Ne ukradi! Ne svjedoči lažno! Poštuj oca svoga i majku!”"},{"v":21,"t":"A onaj će: “Sve sam to čuvao od mladosti.”"},{"v":22,"t":"Čuvši to, Isus mu reče: “Još ti jedno preostaje: sve što imaš prodaj i razdaj siromasima pa ćeš imati blago na nebu. A onda dođi i idi za mnom.”"},{"v":23,"t":"Kad je on to čuo, ražalosti se jer bijaše silno bogat."},{"v":24,"t":"Vidjevši ga, reče Isus: “Kako li je teško imućnicima u kraljevstvo Božje!"},{"v":25,"t":"Lakše je devi kroz uši iglene nego bogatašu u kraljevstvo Božje.”"},{"v":26,"t":"Koji su to čuli, rekoše: “Pa tko se onda može spasiti?”"},{"v":27,"t":"A on će: “Što je nemoguće ljudima, moguće je Bogu.”"},{"v":28,"t":"Nato reče Petar: “Evo, mi ostavismo svoje i pođosmo za tobom.”"},{"v":29,"t":"Isus će im: “Zaista, kažem vam, nema ga tko bi ostavio kuću, ili ženu, ili braću, ili roditelje, ili djecu poradi kraljevstva Božjega,"},{"v":30,"t":"a da ne bi primio mnogostruko već u ovom vremenu, i u budućem vijeku život vječni.”"},{"v":31,"t":"I uzevši sa sobom dvanaestoricu, reče im: “Evo uzlazimo u Jeruzalem i na Sinu Čovječjem ispunit će se sve što su napisali proroci:"},{"v":32,"t":"doista, bit će predan poganima, izrugan, zlostavljan i popljuvan;"},{"v":33,"t":"i pošto ga izbičuju, ubit će ga, ali on će treći dan ustati.”"},{"v":34,"t":"No oni ništa od toga ne razumješe. Te im riječi bijahu skrivene i ne shvaćahu što bijaše rečeno."},{"v":35,"t":"A kad se približavao Jerihonu, neki slijepac sjedio kraj puta i prosio."},{"v":36,"t":"Čuvši gdje mnoštvo prolazi, raspitivao se što je to."},{"v":37,"t":"Rekoše mu: “Isus Nazarećanin prolazi.”"},{"v":38,"t":"Tada povika: “Isuse, Sine Davidov, smiluj mi se!”"},{"v":39,"t":"Oni ga sprijeda ušutkivali, ali on je još jače vikao: “Sine Davidov, smiluj mi se!”"},{"v":40,"t":"Isus se zaustavi i zapovjedi da ga dovedu k njemu. Kad se on približi, upita ga:"},{"v":41,"t":"“Što hoćeš da ti učinim?” A on će: “Gospodine, da progledam.”"},{"v":42,"t":"Isus će mu: “Progledaj! Vjera te tvoja spasila.”"},{"v":43,"t":"I umah progleda i uputi se za njim slaveći Boga. I sav narod koji to vidje dade hvalu Bogu."}]},"19":{"fa":[{"v":1,"t":"پس وارد اریحا شده، از آنجا می گذشت."},{"v":2,"t":"که ناگاه شخصی زکی نام که رئیس باجگیران و دولتمند بود،"},{"v":3,"t":"خواست عیسی را ببیند که کیست و از کثرت خلق نتوانست، زیرا کوتاه قد بود."},{"v":4,"t":"پس پیش دویده بردرخت افراغی برآمد تا او را ببیند. چونکه اومی خواست از آن راه عبور کند."},{"v":5,"t":"و چون عیسی به آن مکان رسید، بالا نگریسته او را دید و گفت: «ای زکی بشتاب و به زیر بیا زیرا که باید امروز درخانه تو بمانم.»"},{"v":6,"t":"پس به زودی پایین شده او را به خرمی پذیرفت."},{"v":7,"t":"و همه چون این را دیدند، همهمه‌کنان می‌گفتند که در خانه شخصی گناهکار به میهمانی رفته است."},{"v":8,"t":"اما زکی برپا شده به خداوند گفت: «الحال‌ای خداوند نصف مایملک خود را به فقرامی دهم و اگر چیزی ناحق از کسی گرفته باشم، چهار برابر بدو رد می‌کنم.»"},{"v":9,"t":"عیسی به وی گفت: «امروز نجات در این خانه پیدا شد. زیرا که این شخص هم پسر ابراهیم است."},{"v":10,"t":"زیرا که پسرانسان آمده است تا گمشده را بجوید و نجات‌بخشد.»"},{"v":11,"t":"و چون ایشان این را شنیدند او مثلی زیادکرده آورد چونکه نزدیک به اورشلیم بود و ایشان گمان می‌بردند که ملکوت خدا می‌باید در همان زمان ظهور کند."},{"v":12,"t":"پس گفت: «شخصی شریف به دیار بعید سفر کرد تا ملکی برای خود گرفته مراجعت کند."},{"v":13,"t":"پس ده نفر از غلامان خود راطلبیده ده قنطار به ایشان سپرده فرمود، تجارت کنید تا بیایم."},{"v":14,"t":"اما اهل ولایت او، چونکه او رادشمن می‌داشتند ایلچیان در عقب او فرستاده گفتند، نمی خواهیم این شخص بر ما سلطنت کند."},{"v":15,"t":"و چون ملک را گرفته مراجعت کرده بود، فرمود تا آن غلامانی را که به ایشان نقد سپرده بودحاضر کنند تا بفهمد هر یک چه سود نموده است."},{"v":16,"t":"پس اولی آمده گفت، ای آقا قنطار تو ده قنطار دیگر نفع آورده است."},{"v":17,"t":"بدو گفت آفرین‌ای غلام نیکو. چونکه بر چیز کم امین بودی بر ده شهر حاکم شو."},{"v":18,"t":"و دیگری آمده گفت، ای آقاقنطار تو پنج قنطار سود کرده است."},{"v":19,"t":"او را نیزفرمود بر پنج شهر حکمرانی کن."},{"v":20,"t":"و سومی آمده گفت، ای آقا اینک قنطار تو موجود است، آن را در پارچه‌ای نگاه داشته‌ام."},{"v":21,"t":"زیرا که از توترسیدم چونکه مرد تندخویی هستی. آنچه نگذارده‌ای، برمی داری و از آنچه نکاشته‌ای درومی کنی."},{"v":22,"t":"به وی گفت، از زبان خودت بر توفتوی می‌دهم، ای غلام شریر. دانسته‌ای که من مرد تندخویی هستم که برمیدارم آنچه رانگذاشته‌ام و درو می‌کنم آنچه را نپاشیده‌ام."},{"v":23,"t":"پس برای چه نقد مرا نزد صرافان نگذاردی تاچون آیم آن را با سود دریافت کنم؟"},{"v":24,"t":"پس به حاضرین فرمود قنطار را از این شخص بگیرید وبه صاحب ده قنطار بدهید."},{"v":25,"t":"به او گفتند‌ای خداوند، وی ده قنطار دارد."},{"v":26,"t":"زیرا به شمامی گویم به هر‌که دارد داده شود و هر‌که نداردآنچه دارد نیز از او گرفته خواهد شد."},{"v":27,"t":"اما آن دشمنان من که نخواستند من بر ایشان حکمرانی نمایم، در اینجا حاضر ساخته پیش من به قتل رسانید.»"},{"v":28,"t":"و چون این را گفت، پیش رفته متوجه اورشلیم گردید."},{"v":29,"t":"و چون نزدیک بیت‌فاجی وبیت عنیا بر کوه مسمی به زیتون رسید، دو نفر ازشاگردان خود را فرستاده،"},{"v":30,"t":"گفت: «به آن قریه‌ای که پیش روی شما است بروید و چون داخل آن شدید، کره الاغی بسته خواهید یافت که هیچ‌کس بر آن هرگز سوار نشده. آن را باز کرده بیاورید."},{"v":31,"t":"و اگر کسی به شما گوید، چرا این راباز می‌کنید، به وی گویید خداوند او را لازم دارد.»"},{"v":32,"t":"پس فرستادگان رفته آن چنانکه بدیشان گفته بود یافتند."},{"v":33,"t":"و چون کره را باز می‌کردند، مالکانش به ایشان گفتند چرا کره را باز می‌کنید؟"},{"v":34,"t":"گفتند خداوند او را لازم دارد."},{"v":35,"t":"پس او را به نزد عیسی آوردند و رخت خود را بر کره افکنده، عیسی را سوار کردند."},{"v":36,"t":"و هنگامی که او می‌رفت جامه های خود را در راه می‌گستردند."},{"v":37,"t":"و چون نزدیک به‌سرازیری کوه زیتون رسید، تمامی شاگردانش شادی کرده، به آوازبلند خدا را حمد گفتن شروع کردند، به‌سبب همه قواتی که از او دیده بودند."},{"v":38,"t":"و می‌گفتند مبارک باد آن پادشاهی که می‌آید، به نام خداوند سلامتی در آسمان و جلال در اعلی علیین باد."},{"v":39,"t":"آنگاه بعضی از فریسیان از آن میان بدو گفتند: «ای استاد شاگردان خود را نهیب نما.»"},{"v":40,"t":"او درجواب ایشان گفت: «به شما می‌گویم اگراینها ساکت شوند، هرآینه سنگها به صداآیند.»"},{"v":41,"t":"و چون نزدیک شده، شهر را نظاره کرد برآن گریان گشته،"},{"v":42,"t":"گفت: «اگر تو نیز می‌دانستی هم در این زمان خود آنچه باعث سلامتی تومیشد، لاکن الحال از چشمان تو پنهان گشته است."},{"v":43,"t":"زیرا ایامی بر تو می‌آید که دشمنانت گرد تو سنگرها سازند و تو را احاطه کرده از هرجانب محاصره خواهند نمود."},{"v":44,"t":"و تو را وفرزندانت را در اندرون تو بر خاک خواهند افکندو در تو سنگی بر سنگی نخواهند گذاشت زیرا که ایام تفقد خود را ندانستی.»"},{"v":45,"t":"و چون داخل هیکل شد، کسانی را که درآنجا خرید و فروش می‌کردند، به بیرون نمودن آغاز کرد."},{"v":46,"t":"و به ایشان گفت: «مکتوب است که خانه من خانه عبادت است لیکن شما آن را مغاره دزدان ساخته‌اید.»"},{"v":47,"t":"و هر روز در هیکل تعلیم می‌داد، اما روسای کهنه و کاتبان و اکابر قوم قصدهلاک نمودن او می‌کردند."},{"v":48,"t":"و نیافتند چه کنندزیرا که تمامی مردم بر او آویخته بودند که از اوبشنوند."}],"en":[{"v":1,"t":"He entered and was passing through Jericho."},{"v":2,"t":"There was a man named Zacchaeus. He was a chief tax collector, and he was rich."},{"v":3,"t":"He was trying to see who Jesus was, and couldn’t because of the crowd, because he was short."},{"v":4,"t":"He ran on ahead and climbed up into a sycamore tree to see him, for he was going to pass that way."},{"v":5,"t":"When Jesus came to the place, he looked up and saw him, and said to him, “Zacchaeus, hurry and come down, for today I must stay at your house.”"},{"v":6,"t":"He hurried, came down, and received him joyfully."},{"v":7,"t":"When they saw it, they all murmured, saying, “He has gone in to lodge with a man who is a sinner.”"},{"v":8,"t":"Zacchaeus stood and said to the Lord, “Behold, Lord, half of my goods I give to the poor. If I have wrongfully exacted anything of anyone, I restore four times as much.”"},{"v":9,"t":"Jesus said to him, “Today, salvation has come to this house, because he also is a son of Abraham."},{"v":10,"t":"For the Son of Man came to seek and to save that which was lost.”"},{"v":11,"t":"As they heard these things, he went on and told a parable, because he was near Jerusalem, and they supposed that God’s Kingdom would be revealed immediately."},{"v":12,"t":"He said therefore, “A certain nobleman went into a far country to receive for himself a kingdom and to return."},{"v":13,"t":"He called ten servants of his and gave them ten mina coins, and told them, ‘Conduct business until I come.’"},{"v":14,"t":"But his citizens hated him, and sent an envoy after him, saying, ‘We don’t want this man to reign over us.’"},{"v":15,"t":"“When he had come back again, having received the kingdom, he commanded these servants, to whom he had given the money, to be called to him, that he might know what they had gained by conducting business."},{"v":16,"t":"The first came before him, saying, ‘Lord, your mina has made ten more minas.’"},{"v":17,"t":"“He said to him, ‘Well done, you good servant! Because you were found faithful with very little, you shall have authority over ten cities.’"},{"v":18,"t":"“The second came, saying, ‘Your mina, Lord, has made five minas.’"},{"v":19,"t":"“So he said to him, ‘And you are to be over five cities.’"},{"v":20,"t":"Another came, saying, ‘Lord, behold, your mina, which I kept laid away in a handkerchief,"},{"v":21,"t":"for I feared you, because you are an exacting man. You take up that which you didn’t lay down, and reap that which you didn’t sow.’"},{"v":22,"t":"“He said to him, ‘Out of your own mouth I will judge you, you wicked servant! You knew that I am an exacting man, taking up that which I didn’t lay down and reaping that which I didn’t sow."},{"v":23,"t":"Then why didn’t you deposit my money in the bank, and at my coming, I might have earned interest on it?’"},{"v":24,"t":"He said to those who stood by, ‘Take the mina away from him and give it to him who has the ten minas.’"},{"v":25,"t":"“They said to him, ‘Lord, he has ten minas!’"},{"v":26,"t":"‘For I tell you that to everyone who has, will more be given; but from him who doesn’t have, even that which he has will be taken away from him."},{"v":27,"t":"But bring those enemies of mine who didn’t want me to reign over them here, and kill them before me.’”"},{"v":28,"t":"Having said these things, he went on ahead, going up to Jerusalem."},{"v":29,"t":"When he came near to Bethsphage and Bethany, at the mountain that is called Olivet, he sent two of his disciples,"},{"v":30,"t":"saying, “Go your way into the village on the other side, in which, as you enter, you will find a colt tied, which no man has ever sat upon. Untie it and bring it."},{"v":31,"t":"If anyone asks you, ‘Why are you untying it?’ say to him: ‘The Lord needs it.’”"},{"v":32,"t":"Those who were sent went away and found things just as he had told them."},{"v":33,"t":"As they were untying the colt, its owners said to them, “Why are you untying the colt?”"},{"v":34,"t":"They said, “The Lord needs it.”"},{"v":35,"t":"Then they brought it to Jesus. They threw their cloaks on the colt and sat Jesus on them."},{"v":36,"t":"As he went, they spread their cloaks on the road."},{"v":37,"t":"As he was now getting near, at the descent of the Mount of Olives, the whole multitude of the disciples began to rejoice and praise God with a loud voice for all the mighty works which they had seen,"},{"v":38,"t":"saying, “Blessed is the King who comes in the name of the Lord! Peace in heaven, and glory in the highest!”"},{"v":39,"t":"Some of the Pharisees from the multitude said to him, “Teacher, rebuke your disciples!”"},{"v":40,"t":"He answered them, “I tell you that if these were silent, the stones would cry out.”"},{"v":41,"t":"When he came near, he saw the city and wept over it,"},{"v":42,"t":"saying, “If you, even you, had known today the things which belong to your peace! But now, they are hidden from your eyes."},{"v":43,"t":"For the days will come on you when your enemies will throw up a barricade against you, surround you, hem you in on every side,"},{"v":44,"t":"and will dash you and your children within you to the ground. They will not leave in you one stone on another, because you didn’t know the time of your visitation.”"},{"v":45,"t":"He entered into the temple and began to drive out those who bought and sold in it,"},{"v":46,"t":"saying to them, “It is written, ‘My house is a house of prayer,’ but you have made it a ‘den of robbers’!”"},{"v":47,"t":"He was teaching daily in the temple, but the chief priests, the scribes, and the leading men among the people sought to destroy him."},{"v":48,"t":"They couldn’t find what they might do, for all the people hung on to every word that he said."}],"hr":[{"v":1,"t":"I uđe u Jerihon. Dok je njime prolazio,"},{"v":2,"t":"eto čovjeka imenom Zakej. Bijaše on nadcarinik, i to bogat."},{"v":3,"t":"Želio je vidjeti tko je to Isus, ali ne mogaše od mnoštva jer je bio niska stasa."},{"v":4,"t":"Potrča naprijed, pope se na smokvu da ga vidi jer je onuda imao proći."},{"v":5,"t":"Kad Isus dođe na to mjesto, pogleda gore i reče mu: “Zakeju, žurno siđi! Danas mi je proboraviti u tvojoj kući.”"},{"v":6,"t":"On žurno siđe i primi ga sav radostan."},{"v":7,"t":"A svi koji to vidješe stadoše mrmljati: “Čovjeku se grešniku svratio!”"},{"v":8,"t":"A Zakej usta i reče Gospodinu: “Evo, Gospodine, polovicu svog imanja dajem siromasima! I ako sam koga u čemu prevario, vraćam četverostruko.”"},{"v":9,"t":"Reče mu na to Isus: “Danas je došlo spasenje ovoj kući jer i on je sin Abrahamov!"},{"v":10,"t":"Ta Sin Čovječji dođe potražiti i spasiti izgubljeno!”"},{"v":11,"t":"Kako su oni to slušali, dometnu on prispodobu - zato što bijaše nadomak Jeruzalemu i oni mislili da će se umah pojaviti kraljevstvo Božje."},{"v":12,"t":"Reče dakle: “Neki je ugledan čovjek imao otputovati u daleku zemlju da primi svoje kraljevstvo pa da se vrati."},{"v":13,"t":"Dozva svojih deset slugu, dade im deset mna i reče: 'Trgujte dok ne dođem.'"},{"v":14,"t":"A njegovi ga građani mrzili te poslaše za njim poslanstvo s porukom: 'Nećemo da se ovaj zakralji nad nama.'”"},{"v":15,"t":"“Kad je on primio kraljevstvo i vratio se, naredi da mu dozovu one sluge kojima je predao novac da sazna što su zaradili.”"},{"v":16,"t":"“Pristupi prvi i reče: 'Gospodaru, tvoja mna donije deset mna.'"},{"v":17,"t":"Reče mu: 'Valjaš, slugo dobri! U najmanjem si bio vjeran, vladaj nad deset gradova!'"},{"v":18,"t":"Dođe i drugi govoreći: 'Mna je tvoja, gospodaru, donijela pet mna.'"},{"v":19,"t":"I tomu reče: 'I ti budi nad pet gradova!'”"},{"v":20,"t":"“Treći, opet dođe govoreći: 'Gospodaru, evo ti tvoje mne. Držao sam je pohranjenu u rupcu."},{"v":21,"t":"Bojao sam te se jer si čovjek strog: uzimaš što nisi pohranio, žanješ što nisi posijao.'”"},{"v":22,"t":"“Kaže mu: 'Iz tvojih te usta sudim, zli slugo! Znao si da sam čovjek strog, da uzimam što nisam pohranio i žanjem što nisam posijao?"},{"v":23,"t":"Zašto onda nisi uložio moj novac u novčarnicu? Ja bih ga po povratku podigao s dobitkom.'"},{"v":24,"t":"Nato reče nazočnima: 'Uzmite od njega mnu i dajte onomu koji ih ima deset.'"},{"v":25,"t":"Rekoše mu: 'Gospodaru, ta već ima deset mna!'"},{"v":26,"t":"Kažem vam: svakomu koji ima još će se dati, a od onoga koji nema oduzet će se i ono što ima."},{"v":27,"t":"A moje neprijatelje - one koji me ne htjedoše za kralja - dovedite ovamo i smaknite ih pred mojim očima!'”"},{"v":28,"t":"Rekavši to, nastavi put uzlazeći u Jeruzalem."},{"v":29,"t":"Kad se približi Betfagi i Betaniji, uz goru koja se zove Maslinska, posla dvojicu učenika"},{"v":30,"t":"govoreći: “Hajdete u selo pred vama. Čim uđete u nj, naći ćete privezano magare koje još nitko nije zajahao. Odriješite ga i dovedite."},{"v":31,"t":"Upita li vas tko: 'Zašto driješite?', ovako recite: 'Gospodinu treba.'”"},{"v":32,"t":"Oni koji bijahu poslani otiđoše i nađoše kako im bijaše rekao."},{"v":33,"t":"I dok su driješili magare, rekoše im gospodari: “Što driješite magare?”"},{"v":34,"t":"Oni odgovore: “Gospodinu treba.”"},{"v":35,"t":"I dovedoše ga Isusu i staviše svoje haljine na magare te posjednuše Isusa."},{"v":36,"t":"I kuda bi on prolazio, prostirali bi po putu svoje haljine."},{"v":37,"t":"A kad se već bio približio obronku Maslinske gore, sve ono mnoštvo učenika, puno radosti, poče iza glasa hvaliti Boga za sva silna djela što ih vidješe:"},{"v":38,"t":"“Blagoslovljen Kralj, Onaj koji dolazi u ime Gospodnje! Na nebu mir! Slava na visinama!”"},{"v":39,"t":"Nato mu neki farizeji iz mnoštva rekoše: “Učitelju, prekori svoje učenike.”"},{"v":40,"t":"On odgovori: “Kažem vam, ako ovi ušute, kamenje će vikati!”"},{"v":41,"t":"Kad se približi i ugleda grad, zaplaka nad njim"},{"v":42,"t":"govoreći: “O kad bi i ti u ovaj dan spoznao što je za tvoj mir!"},{"v":43,"t":"Ali sada je sakriveno tvojim očima. Doći će dani na tebe kad će te neprijatelji tvoji opkoliti opkopom, okružit će te i pritijesniti odasvud."},{"v":44,"t":"Smrskat će o zemlju tebe i djecu tvoju u tebi. I neće ostaviti u tebi ni kamena na kamenu zbog toga što nisi upoznao časa svoga pohođenja.”"},{"v":45,"t":"Ušavši u Hram, stane izgoniti prodavače."},{"v":46,"t":"Kaže im: “Pisano je: Dom moj bit će Dom molitve, a vi od njega načiniste pećinu razbojničku!”"},{"v":47,"t":"I danomice naučavaše u Hramu. A glavari su svećenički i pismoznanci tražili kako da ga pogube, a tako i prvaci narodni,"},{"v":48,"t":"ali nikako naći što da učine jer je sav narod visio o njegovoj riječi."}]},"20":{"fa":[{"v":1,"t":"روزی از آن روزها واقع شد هنگامی که او قوم را در هیکل تعلیم و بشارت می‌داد که روسا کهنه و کاتبان با مشایخ آمده،"},{"v":2,"t":"به وی گفتند: «به ما بگو که به چه قدرت این کارها رامی کنی و کیست که این قدرت را به تو داده است؟»"},{"v":3,"t":"در جواب ایشان گفت: «من نیز از شماچیزی می‌پرسم. به من بگویید."},{"v":4,"t":"تعمید یحیی ازآسمان بود یا از مردم؟»"},{"v":5,"t":"ایشان با خود اندیشیده، گفتند که اگر گوییم از آسمان، هرآینه گوید چرا به او ایمان نیاوردید؟"},{"v":6,"t":"و اگر گوییم از انسان، تمامی قوم ما را سنگسار کنند زیرا یقین می‌دارند که یحیی نبی است.»"},{"v":7,"t":"پس جواب دادند که «نمی دانیم از کجا بود.»"},{"v":8,"t":"عیسی به ایشان گفت: «من نیز شما را نمی گویم که این کارها را به چه قدرت به‌جا می‌آورم.»"},{"v":9,"t":"و این مثل را به مردم گفتن گرفت که «شخصی تاکستانی غرس کرد و به باغبانش سپرده مدت مدیدی سفر کرد."},{"v":10,"t":"و در موسم غلامی نزدباغبانان فرستاد تا از میوه باغ بدو سپارند. اماباغبانان او را زده، تهی‌دست بازگردانیدند."},{"v":11,"t":"پس غلامی دیگر روانه نمود. او را نیز تازیانه زده بی‌حرمت کرده، تهی‌دست بازگردانیدند."},{"v":12,"t":"و بازسومی فرستاد. او را نیز مجروح ساخته بیرون افکندند."},{"v":13,"t":"آنگاه صاحب باغ گفت چه کنم؟ پسرحبیب خود را می‌فرستم شاید چون او را بینند احترام خواهند نمود."},{"v":14,"t":"اما چون باغبانان او رادیدند، با خود تفکرکنان گفتند، این وارث می‌باشد، بیایید او را بکشیم تا میراث از آن ماگردد."},{"v":15,"t":"در حال او را از باغ بیرون افکنده کشتند. پس صاحب باغ بدیشان چه خواهد کرد؟"},{"v":16,"t":"اوخواهد آمد و باغبانان را هلاک کرده باغ را به دیگران خواهد سپرد.» پس چون شنیدند گفتندحاشا."},{"v":17,"t":"به ایشان نظر افکنده گفت: «پس معنی‌این نوشته چیست، سنگی را که معماران ردکردند، همان سر زاویه شده است."},{"v":18,"t":"و هر‌که برآن سنگ افتد خرد شود، اما اگر آن بر کسی بیفتداو را نرم خواهد ساخت؟»"},{"v":19,"t":"آنگاه روسای کهنه و کاتبان خواستند که در همان ساعت او را گرفتارکنند. لیکن از قوم ترسیدند زیرا که دانستند که این مثل را درباره ایشان زده بود."},{"v":20,"t":"و مراقب او بوده جاسوسان فرستادند که خود را صالح می‌نمودند تا سخنی از او گرفته، اورا به حکم و قدرت والی بسپارند."},{"v":21,"t":"پس از اوسوال نموده گفتند: «ای استاد می‌دانیم که تو به راستی سخن می‌رانی و تعلیم می‌دهی و از کسی روداری نمی کنی، بلکه طریق خدا را به صدق می‌آموزی،"},{"v":22,"t":"آیا بر ما جایز هست که جزیه به قیصر بدهیم یا نه؟»"},{"v":23,"t":"او چون مکر ایشان را درک کرد، بدیشان گفت: «مرا برای چه امتحان می‌کنید؟"},{"v":24,"t":"دیناری به من نشان دهید. صورت ورقمش از کیست؟ «ایشان در جواب گفتند: «از قیصر است.»"},{"v":25,"t":"او به ایشان گفت: «پس مال قیصررا به قیصر رد کنید و مال خدا را به خدا.»"},{"v":26,"t":"پس چون نتوانستند او را به سخنی در نظر مردم ملزم سازند، از جواب او در عجب شده ساکت ماندند."},{"v":27,"t":"و بعضی از صدوقیان که منکر قیامت هستند، پیش آمده از وی سوال کرده،"},{"v":28,"t":"گفتند: «ای استاد، موسی برای ما نوشته است که اگرکسی را برادری که زن داشته باشد بمیرد وبی اولاد فوت شود، باید برادرش آن زن را بگیردتا برای برادر خود نسلی آورد."},{"v":29,"t":"پس هفت برادربودند که اولی زن گرفته اولاد ناآورده، فوت شد."},{"v":30,"t":"بعد دومین آن زن را گرفته، او نیز بی‌اولاد بمرد."},{"v":31,"t":"پس سومین او را گرفت و همچنین تا هفتمین وهمه فرزند ناآورده، مردند."},{"v":32,"t":"و بعد از همه، آن زن نیز وفات یافت."},{"v":33,"t":"پس در قیامت، زن کدام‌یک از ایشان خواهد بود، زیرا که هر هفت او راداشتند؟»"},{"v":34,"t":"عیسی در جواب ایشان گفت: «ابنای این عالم نکاح می‌کنند و نکاح کرده می‌شوند."},{"v":35,"t":"لیکن آنانی که مستحق رسیدن به آن عالم و به قیامت از مردگان شوند، نه نکاح می‌کنند و نه نکاح کرده می‌شوند."},{"v":36,"t":"زیرا ممکن نیست که دیگربمیرند از آن جهت که مثل فرشتگان و پسران خدامی باشند، چونکه پسران قیامت هستند."},{"v":37,"t":"و امااینکه مردگان برمی خیزند، موسی نیز در ذکر بوته نشان داد، چنانکه خداوند را خدای ابراهیم وخدای اسحاق و خدای یعقوب خواند."},{"v":38,"t":"و حال آنکه خدای مردگان نیست بلکه خدای زندگان است. زیرا همه نزد او زنده هستند.»"},{"v":39,"t":"پس بعضی از کاتبان در جواب گفتند: «ای استاد. نیکوگفتی.»"},{"v":40,"t":"و بعد از آن هیچ‌کس جرات آن نداشت که از وی سوالی کند."},{"v":41,"t":"پس به ایشان گفت: «چگونه می‌گویند که مسیح پسر داود است"},{"v":42,"t":"و خود داود در کتاب زبور می‌گوید، خداوند به خداوند من گفت به‌دست راست من بنشین"},{"v":43,"t":"تا دشمنان تو راپای انداز تو سازم؟"},{"v":44,"t":"پس چون داود او راخداوند می‌خواند چگونه پسر او می‌باشد؟»"},{"v":45,"t":"و چون تمامی قوم می‌شنیدند، به شاگردان خود گفت:"},{"v":46,"t":"«بپرهیزید از کاتبانی که خرامیدن در لباس دراز را می‌پسندند و سلام در بازارها وصدر کنایس و بالا نشستن در ضیافتها را دوست می‌دارند."},{"v":47,"t":"و خانه های بیوه‌زنان را می‌بلعند ونماز را به ریاکاری طول می‌دهند. اینها عذاب شدیدتر خواهند یافت.»"}],"en":[{"v":1,"t":"On one of those days, as he was teaching the people in the temple and preaching the Good News, the priests and scribes came to him with the elders."},{"v":2,"t":"They asked him, “Tell us: by what authority do you do these things? Or who is giving you this authority?”"},{"v":3,"t":"He answered them, “I also will ask you one question. Tell me:"},{"v":4,"t":"the baptism of John, was it from heaven, or from men?”"},{"v":5,"t":"They reasoned with themselves, saying, “If we say, ‘From heaven,’ he will say, ‘Why didn’t you believe him?’"},{"v":6,"t":"But if we say, ‘From men,’ all the people will stone us, for they are persuaded that John was a prophet.”"},{"v":7,"t":"They answered that they didn’t know where it was from."},{"v":8,"t":"Jesus said to them, “Neither will I tell you by what authority I do these things.”"},{"v":9,"t":"He began to tell the people this parable: “A man planted a vineyard and rented it out to some farmers, and went into another country for a long time."},{"v":10,"t":"At the proper season, he sent a servant to the farmers to collect his share of the fruit of the vineyard. But the farmers beat him and sent him away empty."},{"v":11,"t":"He sent yet another servant, and they also beat him and treated him shamefully, and sent him away empty."},{"v":12,"t":"He sent yet a third, and they also wounded him and threw him out."},{"v":13,"t":"The lord of the vineyard said, ‘What shall I do? I will send my beloved son. It may be that seeing him, they will respect him.’"},{"v":14,"t":"“But when the farmers saw him, they reasoned among themselves, saying, ‘This is the heir. Come, let’s kill him, that the inheritance may be ours.’"},{"v":15,"t":"Then they threw him out of the vineyard and killed him. What therefore will the lord of the vineyard do to them?"},{"v":16,"t":"He will come and destroy these farmers, and will give the vineyard to others.” When they heard that, they said, “May that never be!”"},{"v":17,"t":"But he looked at them and said, “Then what is this that is written, ‘The stone which the builders rejected was made the chief cornerstone’?"},{"v":18,"t":"Everyone who falls on that stone will be broken to pieces, but it will crush whomever it falls on to dust.”"},{"v":19,"t":"The chief priests and the scribes sought to lay hands on him that very hour, but they feared the people—for they knew he had spoken this parable against them."},{"v":20,"t":"They watched him and sent out spies, who pretended to be righteous, that they might trap him in something he said, so as to deliver him up to the power and authority of the governor."},{"v":21,"t":"They asked him, “Teacher, we know that you say and teach what is right, and aren’t partial to anyone, but truly teach the way of God."},{"v":22,"t":"Is it lawful for us to pay taxes to Caesar, or not?”"},{"v":23,"t":"But he perceived their craftiness, and said to them, “Why do you test me?"},{"v":24,"t":"Show me a denarius. Whose image and inscription are on it?” They answered, “Caesar’s.”"},{"v":25,"t":"He said to them, “Then give to Caesar the things that are Caesar’s, and to God the things that are God’s.”"},{"v":26,"t":"They weren’t able to trap him in his words before the people. They marveled at his answer and were silent."},{"v":27,"t":"Some of the Sadducees came to him, those who deny that there is a resurrection."},{"v":28,"t":"They asked him, “Teacher, Moses wrote to us that if a man’s brother dies having a wife, and he is childless, his brother should take the wife and raise up children for his brother."},{"v":29,"t":"There were therefore seven brothers. The first took a wife, and died childless."},{"v":30,"t":"The second took her as wife, and he died childless."},{"v":31,"t":"The third took her, and likewise the seven all left no children, and died."},{"v":32,"t":"Afterward the woman also died."},{"v":33,"t":"Therefore in the resurrection whose wife of them will she be? For the seven had her as a wife.”"},{"v":34,"t":"Jesus said to them, “The children of this age marry and are given in marriage."},{"v":35,"t":"But those who are considered worthy to attain to that age and the resurrection from the dead neither marry nor are given in marriage."},{"v":36,"t":"For they can’t die any more, for they are like the angels and are children of God, being children of the resurrection."},{"v":37,"t":"But that the dead are raised, even Moses showed at the bush, when he called the Lord ‘The God of Abraham, the God of Isaac, and the God of Jacob.’"},{"v":38,"t":"Now he is not the God of the dead, but of the living, for all are alive to him.”"},{"v":39,"t":"Some of the scribes answered, “Teacher, you speak well.”"},{"v":40,"t":"They didn’t dare to ask him any more questions."},{"v":41,"t":"He said to them, “Why do they say that the Christ is David’s son?"},{"v":42,"t":"David himself says in the book of Psalms, ‘The Lord said to my Lord, “Sit at my right hand,"},{"v":43,"t":"until I make your enemies the footstool of your feet.”’"},{"v":44,"t":"“David therefore calls him Lord, so how is he his son?”"},{"v":45,"t":"In the hearing of all the people, he said to his disciples,"},{"v":46,"t":"“Beware of those scribes who like to walk in long robes, and love greetings in the marketplaces, the best seats in the synagogues, and the best places at feasts;"},{"v":47,"t":"who devour widows’ houses, and for a pretense make long prayers. These will receive greater condemnation.”"}],"hr":[{"v":1,"t":"Jednog dana dok je naučavao narod u Hramu i naviještao evanđelje, ispriječe se glavari svećenički i pismoznanci sa starješinama"},{"v":2,"t":"pa mu dobace: “Reci nam kojom vlašću to činiš ili tko ti dade tu vlast?”"},{"v":3,"t":"On odgovori: “Upitat ću i ja vas. Recite mi:"},{"v":4,"t":"krst Ivanov bijaše li od Neba ili od ljudi?”"},{"v":5,"t":"A oni smišljahu među sobom: “Reknemo li 'od Neba', odvratit će 'Zašto mu ne povjerovaste?'"},{"v":6,"t":"A reknemo li 'od ljudi', sav će nas narod kamenovati. Ta uvjeren je da je Ivan prorok.”"},{"v":7,"t":"I odgovore da ne znaju odakle."},{"v":8,"t":"I Isus reče njima: “Ni ja vama neću kazati kojom vlašću ovo činim.”"},{"v":9,"t":"Zatim uze narodu kazivati ovu prispodobu: “Čovjek posadi vinograd, iznajmi ga vinogradarima i otputova na dulje vrijeme.”"},{"v":10,"t":"“Kada dođe doba, posla slugu vinogradarima da mu dadnu od uroda vinogradskoga. No vinogradari ga istukoše i otposlaše praznih ruku."},{"v":11,"t":"Nato on posla drugoga slugu. Ali oni i toga istukoše, izružiše i otposlaše praznih ruku."},{"v":12,"t":"Posla i trećega. A oni i njega izraniše i izbaciše.”"},{"v":13,"t":"“Nato reče gospodar vinograda: 'Što da učinim? Poslat ću im sina svoga ljubljenoga. Njega će valjda poštovati.'"},{"v":14,"t":"Ali kada ga vinogradari ugledaju, stanu među sobom umovati: 'Ovo je baštinik. Ubijmo ga da baština bude naša.'"},{"v":15,"t":"Izbaciše ga iz vinograda i ubiše.” “Što će dakle učiniti s njima gospodar vinograda?"},{"v":16,"t":"Doći će i pogubiti te vinogradare i dati vinograd drugima.” Koji ga slušahu rekoše: “Bože sačuvaj!”"},{"v":17,"t":"A on ih ošinu pogledom i reče: “A što ono piše: Kamen što ga odbaciše graditelji postade kamen zaglavni?"},{"v":18,"t":"Tko god padne na taj kamen, smrskat će se, a na koga on padne, satrt će ga.”"},{"v":19,"t":"Pismoznanci i glavari svećenički gledahu da istog časa stave ruke na nj, ali se pobojaše naroda. Dobro razumješe da o njima kaza tu prispodobu."},{"v":20,"t":"Vrebajući na nj, poslaše uhode koji su se pravili pravednicima da ga uhvate u riječi pa da ga predaju oblasti i vlasti upraviteljevoj."},{"v":21,"t":"Upitaše ga dakle: “Učitelju, znamo da pravo zboriš i naučavaš te nisi pristran, nego po istini učiš putu Božjem."},{"v":22,"t":"Je li nam dopušteno dati porez caru ili nije?”"},{"v":23,"t":"Proničući njihovu lukavost, reče im:"},{"v":24,"t":"“Pokažite mi denar.” “Čiju ima sliku i natpis?”"},{"v":25,"t":"A oni će: “Carevu.” On im reče: “Stoga dajte caru carevo, a Bogu Božje.”"},{"v":26,"t":"I ne mogoše ga uhvatiti u riječi pred narodom, nego umuknuše zadivljeni njegovim odgovorom."},{"v":27,"t":"Pristupe mu neki od saduceja, koji niječu uskrsnuće. Upitaše ga:"},{"v":28,"t":"“Učitelju! Mojsije nam napisa: Umre li bez djece čiji brat koji imaše ženu, neka njegov brat uzme tu ženu te podigne porod bratu svomu."},{"v":29,"t":"Bijaše tako sedmero braće. Prvi se oženi i umrije bez djece."},{"v":30,"t":"Drugi uze njegovu ženu,"},{"v":31,"t":"onda treći; i tako redom sva sedmorica pomriješe ne ostavivši djece."},{"v":32,"t":"Naposljetku umrije i žena."},{"v":33,"t":"Kojemu će dakle od njih ta žena pripasti o uskrsnuću? Jer sedmorica su je imala za ženu.”"},{"v":34,"t":"Reče im Isus: “Djeca se ovog svijeta žene i udaju."},{"v":35,"t":"No oni koji se nađoše dostojni onog svijeta i uskrsnuća od mrtvih niti se žene niti udaju."},{"v":36,"t":"Zaista, ni umrijeti više ne mogu: anđelima su jednaki i sinovi su Božji jer su sinovi uskrsnuća.”"},{"v":37,"t":"“A da mrtvi ustaju, naznači i Mojsije kad u odlomku o grmu Gospodina zove Bogom Abrahamovim, Bogom Izakovim i Bogom Jakovljevim."},{"v":38,"t":"A nije on Bog mrtvih, nego živih. Ta svi njemu žive!”"},{"v":39,"t":"Neki pismoznanci primijete: “Učitelju! Dobro si rekao!”"},{"v":40,"t":"I nisu se više usuđivali upitati ga bilo što."},{"v":41,"t":"A on im reče: “Kako kažu da je Krist sin Davidov?"},{"v":42,"t":"Ta sam David veli u Knjizi psalama: Reče Gospod Gospodinu mojemu: 'Sjedi mi zdesna"},{"v":43,"t":"dok ne položim neprijatelje tvoje za podnožje nogama tvojim!'"},{"v":44,"t":"David ga dakle naziva Gospodinom. Kako mu je onda sin?”"},{"v":45,"t":"I pred svim narodom reče svojim učenicima:"},{"v":46,"t":"“Čuvajte se pismoznanaca, koji rado hodaju u dugim haljinama, vole pozdrave na trgovima, prva sjedala u sinagogama i pročelja na gozbama,"},{"v":47,"t":"proždiru kuće udovičke, još pod izlikom dugih molitava. Stići će ih to oštrija osuda.”"}]},"21":{"fa":[{"v":1,"t":"و نظر کرده دولتمندانی را دید که هدایای خود را در بیت‌المال می‌اندازند."},{"v":2,"t":"و بیوه‌زنی فقیر را دید که دو فلس در آنجا انداخت."},{"v":3,"t":"پس گفت: «هرآینه به شمامی گویم این بیوه فقیر از جمیع آنها بیشترانداخت."},{"v":4,"t":"زیرا که همه ایشان از زیادتی خود درهدایای خدا انداختند، لیکن این زن از احتیاج خود تمامی معیشت خویش را انداخت."},{"v":5,"t":"و چون بعضی ذکر هیکل می‌کردند که به سنگهای خوب و هدایا آراسته شده است گفت:"},{"v":6,"t":"«ایامی می‌آید که از این چیزهایی که می‌بینید، سنگی بر سنگی گذارده نشود، مگر اینکه به زیرافکنده خواهد شد."},{"v":7,"t":"و از او سوال نموده، گفتند: «ای استاد پس این امور کی واقع می‌شود وعلامت نزدیک شدن این وقایع چیست؟»"},{"v":8,"t":"گفت: «احتیاط کنید که گمراه نشوید. زیرا که بسا به نام من آمده خواهند گفت که من هستم و وقت نزدیک است. پس از عقب ایشان مروید."},{"v":9,"t":"و چون اخبارجنگها و فسادها را بشنوید، مضطرب مشویدزیرا که وقوع این امور اول ضرور است لیکن انتهادر ساعت نیست.»"},{"v":10,"t":"پس به ایشان گفت: «قومی با قومی ومملکتی با مملکتی مقاومت خواهند کرد."},{"v":11,"t":"وزلزله های عظیم در جایها و قحطیها و وباها پدیدو چیزهای هولناک و علامات بزرگ از آسمان ظاهر خواهد شد."},{"v":12,"t":"و قبل از این همه، بر شمادست اندازی خواهند کرد و جفا نموده شما را به کنایس و زندانها خواهند سپرد و در حضورسلاطین و حکام بجهت نام من خواهند برد."},{"v":13,"t":"واین برای شما به شهادت خواهد انجامید."},{"v":14,"t":"پس در دلهای خود قرار دهید که برای حجت آوردن، پیشتر اندیشه نکنید،"},{"v":15,"t":"زیرا که من به شما زبانی وحکمتی خواهم داد که همه دشمنان شما با آن مقاومت و مباحثه نتوانند نمود."},{"v":16,"t":"و شما راوالدین و برادران و خویشان و دوستان تسلیم خواهند کرد و بعضی از شما را به قتل خواهندرسانید."},{"v":17,"t":"و جمیع مردم به جهت نام من شما رانفرت خواهند کرد."},{"v":18,"t":"ولکن مویی از سر شما گم نخواهد شد."},{"v":19,"t":"جانهای خود را به صبر دریابید."},{"v":20,"t":"«و چون بینید که اورشلیم به لشکرهامحاصره شده است آنگاه بدانید که خرابی آن رسیده است."},{"v":21,"t":"آنگاه هر‌که در یهودیه باشد، به کوهستان فرار کند و هر‌که در شهر باشد، بیرون رود و هر‌که در صحرا بود، داخل شهر نشود."},{"v":22,"t":"زیرا که همان است ایام انتقام، تا آنچه مکتوب است تمام شود."},{"v":23,"t":"لیکن وای بر آبستنان وشیردهندگان در آن ایام، زیرا تنگی سخت برروی زمین و غضب بر این قوم حادث خواهد شد."},{"v":24,"t":"و به دم شمشیر خواهند افتاد و در میان جمیع امت‌ها به اسیری خواهند رفت و اورشلیم پایمال امت‌ها خواهد شد تا زمانهای امت‌ها به انجام رسد."},{"v":25,"t":"و در آفتاب و ماه و ستارگان علامات خواهد بود و بر زمین تنگی و حیرت از برای امت‌ها روی خواهد نمود به‌سبب شوریدن دریا وامواجش."},{"v":26,"t":"و دلهای مردم ضعف خواهد کرد از خوف و انتظار آن وقایعی که برربع مسکون ظاهرمی شود، زیرا قوات آسمان متزلزل خواهد شد."},{"v":27,"t":"و آنگاه پسر انسان را خواهند دید که بر ابری سوار شده با قوت و جلال عظیم می‌آید."},{"v":28,"t":"«و چون ابتدای این چیزها بشود راست شده، سرهای خود را بلند کنید از آن جهت که خلاصی شما نزدیک است.»"},{"v":29,"t":"و برای ایشان مثلی گفت که «درخت انجیر و سایر درختان راملاحظه نمایید،"},{"v":30,"t":"که چون می‌بینید شکوفه می‌کند خود می‌دانید که تابستان نزدیک است."},{"v":31,"t":"و همچنین شما نیز چون بینید که این امور واقع می‌شود، بدانید که ملکوت خدا نزدیک شده است."},{"v":32,"t":"هرآینه به شما می‌گویم که تا جمیع این امور واقع نشود، این فرقه نخواهد گذشت."},{"v":33,"t":"آسمان و زمین زایل می‌شود لیکن سخنان من زایل نخواهد شد."},{"v":34,"t":"پس خود را حفظ کنید مبادا دلهای شما ازپرخوری و مستی و اندیشه های دنیوی، سنگین گردد و آن روز ناگهان بر شما آید."},{"v":35,"t":"زیرا که مثل دامی بر جمیع سکنه تمام روی زمین خواهد آمد."},{"v":36,"t":"پس در هر وقت دعا کرده، بیدار باشید تاشایسته آن شوید که از جمیع این چیزهایی که به وقوع خواهد پیوست نجات یابید و در حضورپسر انسان بایستید.»"},{"v":37,"t":"و روزها را در هیکل تعلیم می‌داد و شبها بیرون رفته، در کوه معروف به زیتون به‌سر می‌برد."},{"v":38,"t":"و هر بامداد قوم نزد وی در هیکل می‌شتافتند تا کلام او را بشنوند."}],"en":[{"v":1,"t":"He looked up and saw the rich people who were putting their gifts into the treasury."},{"v":2,"t":"He saw a certain poor widow casting in two small brass coins."},{"v":3,"t":"He said, “Truly I tell you, this poor widow put in more than all of them,"},{"v":4,"t":"for all these put in gifts for God from their abundance, but she, out of her poverty, put in all that she had to live on.”"},{"v":5,"t":"As some were talking about the temple and how it was decorated with beautiful stones and gifts, he said,"},{"v":6,"t":"“As for these things which you see, the days will come in which there will not be left here one stone on another that will not be thrown down.”"},{"v":7,"t":"They asked him, “Teacher, so when will these things be? What is the sign that these things are about to happen?”"},{"v":8,"t":"He said, “Watch out that you don’t get led astray, for many will come in my name, saying, ‘I am he,’ and, ‘The time is at hand.’ Therefore don’t follow them."},{"v":9,"t":"When you hear of wars and disturbances, don’t be terrified, for these things must happen first, but the end won’t come immediately.”"},{"v":10,"t":"Then he said to them, “Nation will rise against nation, and kingdom against kingdom."},{"v":11,"t":"There will be great earthquakes, famines, and plagues in various places. There will be terrors and great signs from heaven."},{"v":12,"t":"But before all these things, they will lay their hands on you and will persecute you, delivering you up to synagogues and prisons, bringing you before kings and governors for my name’s sake."},{"v":13,"t":"It will turn out as a testimony for you."},{"v":14,"t":"Settle it therefore in your hearts not to meditate beforehand how to answer,"},{"v":15,"t":"for I will give you a mouth and wisdom which all your adversaries will not be able to withstand or to contradict."},{"v":16,"t":"You will be handed over even by parents, brothers, relatives, and friends. They will cause some of you to be put to death."},{"v":17,"t":"You will be hated by all men for my name’s sake."},{"v":18,"t":"And not a hair of your head will perish."},{"v":19,"t":"“By your endurance you will win your lives."},{"v":20,"t":"“But when you see Jerusalem surrounded by armies, then know that its desolation is at hand."},{"v":21,"t":"Then let those who are in Judea flee to the mountains. Let those who are in the middle of her depart. Let those who are in the country not enter therein."},{"v":22,"t":"For these are days of vengeance, that all things which are written may be fulfilled."},{"v":23,"t":"Woe to those who are pregnant and to those who nurse infants in those days! For there will be great distress in the land and wrath to this people."},{"v":24,"t":"They will fall by the edge of the sword, and will be led captive into all the nations. Jerusalem will be trampled down by the Gentiles until the times of the Gentiles are fulfilled."},{"v":25,"t":"“There will be signs in the sun, moon, and stars; and on the earth anxiety of nations, in perplexity for the roaring of the sea and the waves;"},{"v":26,"t":"men fainting for fear and for expectation of the things which are coming on the world, for the powers of the heavens will be shaken."},{"v":27,"t":"Then they will see the Son of Man coming in a cloud with power and great glory."},{"v":28,"t":"But when these things begin to happen, look up and lift up your heads, because your redemption is near.”"},{"v":29,"t":"He told them a parable. “See the fig tree and all the trees."},{"v":30,"t":"When they are already budding, you see it and know by your own selves that the summer is already near."},{"v":31,"t":"Even so you also, when you see these things happening, know that God’s Kingdom is near."},{"v":32,"t":"Most certainly I tell you, this generation will not pass away until all things are accomplished."},{"v":33,"t":"Heaven and earth will pass away, but my words will by no means pass away."},{"v":34,"t":"“So be careful, or your hearts will be loaded down with carousing, drunkenness, and cares of this life, and that day will come on you suddenly."},{"v":35,"t":"For it will come like a snare on all those who dwell on the surface of all the earth."},{"v":36,"t":"Therefore be watchful all the time, praying that you may be counted worthy to escape all these things that will happen, and to stand before the Son of Man.”"},{"v":37,"t":"Every day Jesus was teaching in the temple, and every night he would go out and spend the night on the mountain that is called Olivet."},{"v":38,"t":"All the people came early in the morning to him in the temple to hear him."}],"hr":[{"v":1,"t":"Pogleda i vidje kako bogataši bacaju u riznicu svoje darove."},{"v":2,"t":"A ugleda i neku ubogu udovicu kako baca onamo dva novčića."},{"v":3,"t":"I reče: “Uistinu, kažem vam: ova je sirota udovica ubacila više od sviju."},{"v":4,"t":"Svi su oni zapravo među darove ubacili od svog suviška, a ona je od svoje sirotinje ubacila sav žitak što ga imaše.”"},{"v":5,"t":"I dok su neki razgovarali o Hramu, kako ga resi divno kamenje i zavjetni darovi, reče:"},{"v":6,"t":"“Doći će dani u kojima se od ovoga što motrite neće ostaviti ni kamen na kamenu nerazvaljen.”"},{"v":7,"t":"Upitaše ga: “Učitelju, a kada će to biti? I na koji se znak to ima dogoditi?”"},{"v":8,"t":"A on reče: “Pazite, ne dajte se zavesti. Mnogi će doista doći u moje ime i govoriti: 'Ja sam' i: 'Vrijeme se približilo!' Ne idite za njima."},{"v":9,"t":"A kad čujete za ratove i pobune, ne prestrašite se. Doista treba da se to prije dogodi, ali to još nije odmah svršetak.”"},{"v":10,"t":"Tada im kaza: “Narod će ustati protiv naroda i kraljevstvo protiv kraljevstva."},{"v":11,"t":"I bit će velikih potresa i po raznim mjestima gladi i pošasti; bit će strahota i velikih znakova s neba.”"},{"v":12,"t":"“No prije svega toga podignut će na vas ruke i progoniti vas, predavati vas u sinagoge i tamnice. Vući će vas pred kraljeve i upravitelje zbog imena mojega."},{"v":13,"t":"Zadesit će vas to radi svjedočenja.”"},{"v":14,"t":"“Stoga uzmite k srcu: nemojte unaprijed smišljati obranu!"},{"v":15,"t":"Ta ja ću vam dati usta i mudrost kojoj se neće moći suprotstaviti niti oduprijeti nijedan vaš protivnik."},{"v":16,"t":"A predavat će vas čak i vaši roditelji i braća, rođaci i prijatelji. Neke će od vas i ubiti.”"},{"v":17,"t":"“Svi će vas zamrziti zbog imena mojega."},{"v":18,"t":"Ali ni vlas vam s glave neće propasti."},{"v":19,"t":"Svojom ćete se postojanošću spasiti.”"},{"v":20,"t":"“Kad ugledate da vojska opkoljuje Jeruzalem, tada znajte: približilo se njegovo opustošenje."},{"v":21,"t":"Koji se tada zateknu u Judeji, neka bježe u gore; a koji u Gradu, neka ga napuste; koji pak po poljima, neka se u nj ne vraćaju"},{"v":22,"t":"jer to su dani odmazde, da se ispuni sve što je pisano.”"},{"v":23,"t":"“Jao trudnicama i dojiljama u one dane jer bit će jad velik na zemlji i gnjev nad ovim narodom."},{"v":24,"t":"Padat će od oštrice mača, odvodit će ih kao roblje po svim narodima. I Jeruzalem će gaziti pogani sve dok se ne navrše vremena pogana.”"},{"v":25,"t":"“I bit će znaci na suncu, mjesecu i zvijezdama, a na zemlji bezizlazna tjeskoba naroda zbog huke mora i valovlja."},{"v":26,"t":"Izdisat će ljudi od straha i iščekivanja onoga što prijeti svijetu. Doista, sile će se nebeske poljuljati."},{"v":27,"t":"Tada će ugledati Sina Čovječjega gdje dolazi u oblaku s velikom moći i slavom."},{"v":28,"t":"Kad se sve to stane zbivati, uspravite se i podignite glave jer se približuje vaše otkupljenje.”"},{"v":29,"t":"I reče im prispodobu: “Pogledajte smokvu i sva stabla."},{"v":30,"t":"Kad već propupaju, i sami vidite i znate: blizu je već ljeto."},{"v":31,"t":"Tako i vi kad vidite da se to zbiva, znajte: blizu je kraljevstvo Božje."},{"v":32,"t":"Zaista, kažem vam, ne, neće uminuti naraštaj ovaj dok se sve ne zbude."},{"v":33,"t":"Nebo će i zemlja uminuti, ali moje riječi ne, neće uminuti.”"},{"v":34,"t":"“Pazite na se da vam srca ne otežaju u proždrljivosti, pijanstvu i u životnim brigama te vas iznenada ne zatekne onaj Dan"},{"v":35,"t":"jer će kao zamka nadoći na sve žitelje po svoj zemlji.”"},{"v":36,"t":"“Stoga budni budite i u svako doba molite da uzmognete umaći svemu tomu što se ima zbiti i stati pred Sina Čovječjega.”"},{"v":37,"t":"Danju je učio u Hramu, a noću bi izlazio i noćio na gori zvanoj Maslinska."},{"v":38,"t":"A sav bi narod rano hrlio k njemu u Hram da ga sluša."}]},"22":{"fa":[{"v":1,"t":"و چون عید فطیر که به فصح معروف است نزدیک شد،"},{"v":2,"t":"روسای کهنه وکاتبان مترصد می‌بودند که چگونه او را به قتل رسانند، زیرا که از قوم ترسیدند."},{"v":3,"t":"اما شیطان در یهودای مسمی به اسخریوطی که از‌جمله آن دوازده بود داخل گشت،"},{"v":4,"t":"و اورفته با روسای کهنه و سرداران سپاه گفتگو کرد که چگونه او را به ایشان تسلیم کند."},{"v":5,"t":"ایشان شادشده با او عهد بستند که نقدی به وی دهند."},{"v":6,"t":"و اوقبول کرده در صدد فرصتی برآمد که اورا درنهانی از مردم به ایشان تسلیم کند."},{"v":7,"t":"اما چون روز فطیر که در آن می‌بایست فصح را ذبح کنند رسید،"},{"v":8,"t":"پطرس و یوحنا را فرستاده، گفت: «بروید و فصح را بجهت ما آماده کنید تابخوریم.»"},{"v":9,"t":"به وی گفتند: «در کجا می‌خواهی مهیا کنیم؟»"},{"v":10,"t":"ایشان را گفت: «اینک هنگامی که داخل شهر شوید، شخصی با سبوی آب به شمابرمی خورد. به خانه‌ای که او درآید، از عقب وی بروید،"},{"v":11,"t":"و به صاحب‌خانه گویید، استاد تو را می گوید مهمانخانه کجا است تا در آن فصح را باشاگردان خود بخورم."},{"v":12,"t":"او بالاخانه‌ای بزرگ ومفروش به شما نشان خواهد داد در آنجا مهیاسازید.»"},{"v":13,"t":"پس رفته چنانکه به ایشان گفته بودیافتند و فصح را آماده کردند."},{"v":14,"t":"و چون وقت رسید با دوازده رسول بنشست."},{"v":15,"t":"و به ایشان گفت: «اشتیاق بی‌نهایت داشتم که پیش از زحمت دیدنم، این فصح را باشما بخورم."},{"v":16,"t":"زیرا به شما می‌گویم از این دیگرنمی خورم تا وقتی که در ملکوت خدا تمام شود.»"},{"v":17,"t":"پس پیاله‌ای گرفته، شکر نمود و گفت: «این رابگیرید و در میان خود تقسیم کنید."},{"v":18,"t":"زیرا به شما می‌گویم که تا ملکوت خدا نیاید، از میوه مودیگر نخواهم نوشید.»"},{"v":19,"t":"و نان را گرفته، شکرنمود و پاره کرده، به ایشان داد و گفت: «این است جسد من که برای شما داده می‌شود، این را به یادمن به‌جا آرید.»"},{"v":20,"t":"و همچنین بعد از شام پیاله راگرفت و گفت: «این پیاله عهد جدید است در خون من که برای شما ریخته می‌شود."},{"v":21,"t":"لیکن اینک دست آن کسی‌که مرا تسلیم می‌کند با من در سفره است."},{"v":22,"t":"زیرا که پسر انسان برحسب آنچه مقدراست، می‌رود لیکن وای بر آن کسی‌که او را تسلیم کند.»"},{"v":23,"t":"آنگاه از یکدیگر شروع کردند به پرسیدن که کدام‌یک از ایشان باشد که این کار بکند؟"},{"v":24,"t":"و در میان ایشان نزاعی نیز افتاد که کدام‌یک ازایشان بزرگتر می‌باشد؟"},{"v":25,"t":"آنگاه به ایشان گفت: «سلاطین امت‌ها بر ایشان سروری می‌کنند وحکام خود را ولی‌نعمت می‌خوانند."},{"v":26,"t":"لیکن شماچنین مباشید، بلکه بزرگتر از شما مثل کوچکترباشد و پیشوا چون خادم."},{"v":27,"t":"زیرا کدام‌یک بزرگتراست آنکه به غذا نشیند یا آنکه خدمت کند آیانیست آنکه نشسته است؟ لیکن من در میان شماچون خادم هستم."},{"v":28,"t":"و شما کسانی می‌باشید که در امتحانهای من با من به‌سر بردید."},{"v":29,"t":"و من ملکوتی برای شما قرار می‌دهم چنانکه پدرم برای من مقرر فرمود."},{"v":30,"t":"تا در ملکوت من از خوان من بخورید و بنوشید و بر کرسیها نشسته بردوازده سبط اسرائیل داوری کنید.»"},{"v":31,"t":"پس خداوند گفت: «ای شمعون، ای شمعون، اینک شیطان خواست شما را چون گندم غربال کند،"},{"v":32,"t":"لیکن من برای تو دعا کردم تاایمانت تلف نشود و هنگامی که تو بازگشت کنی برادران خود را استوار نما.»"},{"v":33,"t":"به وی گفت: «ای خداوند حاضرم که با تو بروم حتی در زندان و درموت.»"},{"v":34,"t":"گفت: «تو را می‌گویم‌ای پطرس امروزخروس بانگ نزده باشد که سه مرتبه انکار خواهی کرد که مرا نمی شناسی.»"},{"v":35,"t":"و به ایشان گفت: «هنگامی که شما را بی‌کیسه و توشه‌دان و کفش فرستادم به هیچ‌چیز محتاج شدید؟» گفتند هیچ."},{"v":36,"t":"پس به ایشان گفت: «لیکن الان هر‌که کیسه دارد، آن را بردارد و همچنین توشه‌دان را و کسی‌که شمشیر ندارد جامه خود را فروخته آن رابخرد."},{"v":37,"t":"زیرا به شما می‌گویم که این نوشته در من می‌باید به انجام رسید، یعنی با گناهکاران محسوب شد زیرا هر‌چه در خصوص من است، انقضا دارد."},{"v":38,"t":"گفتند: «ای خداوند اینک دوشمشیر.» به ایشان گفت: «کافی است.»"},{"v":39,"t":"و برحسب عادت بیرون شده به کوه زیتون رفت و شاگردانش از عقب او رفتند."},{"v":40,"t":"و چون به آن موضع رسید، به ایشان گفت: «دعا کنید تا درامتحان نیفتید.»"},{"v":41,"t":"و او از ایشان به مسافت پرتاپ سنگی دور شده، به زانو درآمد و دعا کرده، گفت:"},{"v":42,"t":"«ای پدر اگر بخواهی این پیاله را از من بگردان، لیکن نه به خواهش من بلکه به اراده تو.»"},{"v":43,"t":"وفرشته‌ای از آسمان بر او ظاهر شده او را تقویت می‌نمود."},{"v":44,"t":"پس به مجاهده افتاده به سعی بلیغتردعا کرد، چنانکه عرق او مثل قطرات خون بود که بر زمین می‌ریخت."},{"v":45,"t":"پس از دعا برخاسته نزدشاگردان خود آمده ایشان را از حزن در خواب یافت."},{"v":46,"t":"به ایشان گفت: «برای چه در خواب هستید؟ برخاسته دعا کنید تا در امتحان نیفتید.»"},{"v":47,"t":"و سخن هنوز بر زبانش بود که ناگاه جمعی آمدند و یکی از آن دوازده که یهودا نام داشت بردیگران سبقت جسته نزد عیسی آمد تا او راببوسد."},{"v":48,"t":"و عیسی بدو گفت: «ای یهودا آیا به بوسه پسر انسان را تسلیم می‌کنی؟»"},{"v":49,"t":"رفقایش چون دیدند که چه می‌شود عرض کردند خداوندابه شمشیر بزنیم."},{"v":50,"t":"و یکی از ایشان، غلام رئیس کهنه را زده، گوش راست او را از تن جدا کرد."},{"v":51,"t":"عیسی متوجه شده گفت: «تا به این بگذارید.» وگوش او را لمس نموده، شفا داد."},{"v":52,"t":"پس عیسی به روسای کهنه و سرداران سپاه هیکل و مشایخی که نزد او آمده بودند گفت: «گویا بر دزد با شمشیرها و چوبها بیرون آمدید."},{"v":53,"t":"وقتی که هر روزه در هیکل با شما می‌بودم دست بر من دراز نکردید، لیکن این است ساعت شما و قدرت ظلمت.»"},{"v":54,"t":"پس او را گرفته بردند و به‌سرای رئیس کهنه آوردند و پطرس از دور از عقب می‌آمد."},{"v":55,"t":"و چون در میان ایوان آتش افروخته گردش نشسته بودند، پطرس در میان ایشان بنشست."},{"v":56,"t":"آنگاه کنیزکی چون او را در روشنی آتش نشسته دید بر او چشم دوخته گفت: «این شخص هم با او می‌بود.»"},{"v":57,"t":"او وی را انکار کرده گفت: «ای زن او را نمی شناسم.»"},{"v":58,"t":"بعد از زمانی دیگری او را دیده گفت: «تو از اینها هستی.» پطرس گفت: «ای مرد، من نیستم.»"},{"v":59,"t":"و چون تخمین یک ساعت گذشت یکی دیگر با تاکیدگفت: «بلاشک این شخص از رفقای او است زیراکه جلیلی هم هست.»"},{"v":60,"t":"پطرس گفت: «ای مردنمی دانم چه می‌گویی؟» در همان ساعت که این رامی گفت خروس بانگ زد."},{"v":61,"t":"آنگاه خداوندروگردانیده به پطرس نظر افکند پس پطرس آن کلامی را که خداوند به وی گفته بود به‌خاطرآورد که قبل از بانگ زدن خروس سه مرتبه مراانکار خواهی کرد."},{"v":62,"t":"پس پطرس بیرون رفته زارزار بگریست."},{"v":63,"t":"و کسانی که عیسی را گرفته بودند، او راتازیانه زده استهزا نمودند."},{"v":64,"t":"و چشم او را بسته طپانچه بر رویش زدند و از وی سوال کرده، گفتند: «نبوت کن که تو را زده است؟»"},{"v":65,"t":"و بسیارکفر دیگر به وی گفتند."},{"v":66,"t":"و چون روز شد اهل شورای قوم یعنی روسای کهنه و کاتبان فراهم آمده در مجلس خوداو را آورده،"},{"v":67,"t":"گفتند: «اگر تو مسیح هستی به مابگو: «او به ایشان گفت: «اگر به شما گویم مراتصدیق نخواهید کرد."},{"v":68,"t":"و اگر از شما سوال کنم جواب نمی دهید و مرا رها نمی کنید."},{"v":69,"t":"لیکن بعداز این پسر انسان به طرف راست قوت خداخواهد نشست.»"},{"v":70,"t":"همه گفتند: «پس تو پسر خداهستی؟» او به ایشان گفت: «شما می‌گویید که من هستم.»"},{"v":71,"t":"گفتند: «دیگر ما را چه حاجت به شهادت است، زیرا خود از زبانش شنیدیم.»"}],"en":[{"v":1,"t":"Now the feast of unleavened bread, which is called the Passover, was approaching."},{"v":2,"t":"The chief priests and the scribes sought how they might put him to death, for they feared the people."},{"v":3,"t":"Satan entered into Judas, who was also called Iscariot, who was counted with the twelve."},{"v":4,"t":"He went away and talked with the chief priests and captains about how he might deliver him to them."},{"v":5,"t":"They were glad, and agreed to give him money."},{"v":6,"t":"He consented and sought an opportunity to deliver him to them in the absence of the multitude."},{"v":7,"t":"The day of unleavened bread came, on which the Passover must be sacrificed."},{"v":8,"t":"Jesus sent Peter and John, saying, “Go and prepare the Passover for us, that we may eat.”"},{"v":9,"t":"They said to him, “Where do you want us to prepare?”"},{"v":10,"t":"He said to them, “Behold, when you have entered into the city, a man carrying a pitcher of water will meet you. Follow him into the house which he enters."},{"v":11,"t":"Tell the master of the house, ‘The Teacher says to you, “Where is the guest room, where I may eat the Passover with my disciples?”’"},{"v":12,"t":"He will show you a large, furnished upper room. Make preparations there.”"},{"v":13,"t":"They went, found things as Jesus had told them, and they prepared the Passover."},{"v":14,"t":"When the hour had come, he sat down with the twelve apostles."},{"v":15,"t":"He said to them, “I have earnestly desired to eat this Passover with you before I suffer,"},{"v":16,"t":"for I tell you, I will no longer by any means eat of it until it is fulfilled in God’s Kingdom.”"},{"v":17,"t":"He received a cup, and when he had given thanks, he said, “Take this and share it among yourselves,"},{"v":18,"t":"for I tell you, I will not drink at all again from the fruit of the vine, until God’s Kingdom comes.”"},{"v":19,"t":"He took bread, and when he had given thanks, he broke and gave it to them, saying, “This is my body which is given for you. Do this in memory of me.”"},{"v":20,"t":"Likewise, he took the cup after supper, saying, “This cup is the new covenant in my blood, which is poured out for you."},{"v":21,"t":"But behold, the hand of him who betrays me is with me on the table."},{"v":22,"t":"The Son of Man indeed goes as it has been determined, but woe to that man through whom he is betrayed!”"},{"v":23,"t":"They began to question among themselves which of them it was who would do this thing."},{"v":24,"t":"A dispute also arose among them, which of them was considered to be greatest."},{"v":25,"t":"He said to them, “The kings of the nations lord it over them, and those who have authority over them are called ‘benefactors.’"},{"v":26,"t":"But not so with you. Rather, the one who is greater among you, let him become as the younger, and one who is governing, as one who serves."},{"v":27,"t":"For who is greater, one who sits at the table, or one who serves? Isn’t it he who sits at the table? But I am among you as one who serves."},{"v":28,"t":"“But you are those who have continued with me in my trials."},{"v":29,"t":"I confer on you a kingdom, even as my Father conferred on me,"},{"v":30,"t":"that you may eat and drink at my table in my Kingdom. You will sit on thrones, judging the twelve tribes of Israel.”"},{"v":31,"t":"The Lord said, “Simon, Simon, behold, Satan asked to have all of you, that he might sift you as wheat,"},{"v":32,"t":"but I prayed for you, that your faith wouldn’t fail. You, when once you have turned again, establish your brothers.”"},{"v":33,"t":"He said to him, “Lord, I am ready to go with you both to prison and to death!”"},{"v":34,"t":"He said, “I tell you, Peter, the rooster will by no means crow today until you deny that you know me three times.”"},{"v":35,"t":"He said to them, “When I sent you out without purse, bag, and sandals, did you lack anything?” They said, “Nothing.”"},{"v":36,"t":"Then he said to them, “But now, whoever has a purse, let him take it, and likewise a bag. Whoever has none, let him sell his cloak, and buy a sword."},{"v":37,"t":"For I tell you that this which is written must still be fulfilled in me: ‘He was counted with transgressors.’ For that which concerns me is being fulfilled.”"},{"v":38,"t":"They said, “Lord, behold, here are two swords.” He said to them, “That is enough.”"},{"v":39,"t":"He came out and went, as his custom was, to the Mount of Olives. His disciples also followed him."},{"v":40,"t":"When he was at the place, he said to them, “Pray that you don’t enter into temptation.”"},{"v":41,"t":"He was withdrawn from them about a stone’s throw, and he knelt down and prayed,"},{"v":42,"t":"saying, “Father, if you are willing, remove this cup from me. Nevertheless, not my will, but yours, be done.”"},{"v":43,"t":"An angel from heaven appeared to him, strengthening him."},{"v":44,"t":"Being in agony, he prayed more earnestly. His sweat became like great drops of blood falling down on the ground."},{"v":45,"t":"When he rose up from his prayer, he came to the disciples and found them sleeping because of grief,"},{"v":46,"t":"and said to them, “Why do you sleep? Rise and pray that you may not enter into temptation.”"},{"v":47,"t":"While he was still speaking, a crowd appeared. He who was called Judas, one of the twelve, was leading them. He came near to Jesus to kiss him."},{"v":48,"t":"But Jesus said to him, “Judas, do you betray the Son of Man with a kiss?”"},{"v":49,"t":"When those who were around him saw what was about to happen, they said to him, “Lord, shall we strike with the sword?”"},{"v":50,"t":"A certain one of them struck the servant of the high priest, and cut off his right ear."},{"v":51,"t":"But Jesus answered, “Let me at least do this”—and he touched his ear and healed him."},{"v":52,"t":"Jesus said to the chief priests, captains of the temple, and elders, who had come against him, “Have you come out as against a robber, with swords and clubs?"},{"v":53,"t":"When I was with you in the temple daily, you didn’t stretch out your hands against me. But this is your hour, and the power of darkness.”"},{"v":54,"t":"They seized him and led him away, and brought him into the high priest’s house. But Peter followed from a distance."},{"v":55,"t":"When they had kindled a fire in the middle of the courtyard and had sat down together, Peter sat among them."},{"v":56,"t":"A certain servant girl saw him as he sat in the light, and looking intently at him, said, “This man also was with him.”"},{"v":57,"t":"He denied Jesus, saying, “Woman, I don’t know him.”"},{"v":58,"t":"After a little while someone else saw him and said, “You also are one of them!” But Peter answered, “Man, I am not!”"},{"v":59,"t":"After about one hour passed, another confidently affirmed, saying, “Truly this man also was with him, for he is a Galilean!”"},{"v":60,"t":"But Peter said, “Man, I don’t know what you are talking about!” Immediately, while he was still speaking, a rooster crowed."},{"v":61,"t":"The Lord turned and looked at Peter. Then Peter remembered the Lord’s word, how he said to him, “Before the rooster crows you will deny me three times.”"},{"v":62,"t":"He went out, and wept bitterly."},{"v":63,"t":"The men who held Jesus mocked him and beat him."},{"v":64,"t":"Having blindfolded him, they struck him on the face and asked him, “Prophesy! Who is the one who struck you?”"},{"v":65,"t":"They spoke many other things against him, insulting him."},{"v":66,"t":"As soon as it was day, the assembly of the elders of the people were gathered together, both chief priests and scribes, and they led him away into their council, saying,"},{"v":67,"t":"“If you are the Christ, tell us.” But he said to them, “If I tell you, you won’t believe,"},{"v":68,"t":"and if I ask, you will in no way answer me or let me go."},{"v":69,"t":"From now on, the Son of Man will be seated at the right hand of the power of God.”"},{"v":70,"t":"They all said, “Are you then the Son of God?” He said to them, “You say it, because I am.”"},{"v":71,"t":"They said, “Why do we need any more witness? For we ourselves have heard from his own mouth!”"}],"hr":[{"v":1,"t":"Bližio se Blagdan beskvasnih kruhova zvan Pasha."},{"v":2,"t":"Glavari svećenički i pismoznanci tražili su kako da Isusa smaknu jer se bojahu naroda."},{"v":3,"t":"A Sotona uđe u Judu zvanog Iškariotski koji bijaše iz broja dvanaestorice."},{"v":4,"t":"On ode i ugovori s glavarima svećeničkim i zapovjednicima kako da im ga preda."},{"v":5,"t":"Oni se povesele i ugovore da će mu dati novca."},{"v":6,"t":"On pristade. Otada je tražio priliku da im ga preda mimo naroda."},{"v":7,"t":"Kada dođe Dan beskvasnih kruhova, u koji je trebalo žrtvovati pashu,"},{"v":8,"t":"posla Isus Petra i Ivana i reče: “Hajdete, pripravite nam da blagujemo pashu.”"},{"v":9,"t":"Rekoše mu: “Gdje hoćeš da pripravimo?”"},{"v":10,"t":"On im reče: “Evo, čim uđete u grad, namjerit ćete se na čovjeka koji nosi krčag vode. Pođite za njim u kuću u koju uniđe"},{"v":11,"t":"i recite domaćinu te kuće: 'Učitelj veli: Gdje je svratište u kojem bih blagovao pashu sa svojim učenicima?'"},{"v":12,"t":"I on će vam pokazati na katu veliko blagovalište prostrto: ondje pripravite.”"},{"v":13,"t":"Oni odu, nađu kako im je rekao i priprave pashu."},{"v":14,"t":"Kada dođe čas, sjede Isus za stol i apostoli s njim."},{"v":15,"t":"I reče im: “Svom sam dušom čeznuo ovu pashu blagovati s vama prije svoje muke."},{"v":16,"t":"Jer kažem vam, neću je više blagovati dok se ona ne završi u kraljevstvu Božjem.”"},{"v":17,"t":"I uze čašu, zahvali i reče: “Uzmite je i razdijelite među sobom."},{"v":18,"t":"Jer kažem vam, ne, neću više piti od roda trsova dok kraljevstvo Božje ne dođe.”"},{"v":19,"t":"I uze kruh, zahvali, razlomi i dade im govoreći: “Ovo je tijelo moje koje se za vas predaje. Ovo činite meni na spomen.”"},{"v":20,"t":"Tako i čašu, pošto večeraše, govoreći: “Ova čaša novi je Savez u mojoj krvi koja se za vas prolijeva.”"},{"v":21,"t":"“A evo, ruka mog izdajice sa mnom je na stolu."},{"v":22,"t":"Sin Čovječji, istina, ide kako je određeno, ali jao čovjeku onomu koji ga predaje.”"},{"v":23,"t":"I oni se počeše ispitivati tko bi od njih mogao takvo što učiniti."},{"v":24,"t":"Uto nasta među njima prepirka tko bi od njih bio najveći."},{"v":25,"t":"A on im reče: “Kraljevi gospoduju svojim narodima i vlastodršci nazivaju sebe dobrotvorima."},{"v":26,"t":"Vi nemojte tako! Naprotiv, najveći među vama neka bude kao najmlađi; i predstojnik kao poslužitelj."},{"v":27,"t":"Ta tko je veći? Koji je za stolom ili koji poslužuje? Zar ne onaj koji je za stolom? A ja sam posred vas kao onaj koji poslužuje.”"},{"v":28,"t":"“Da, vi ste sa mnom ustrajali u mojim kušnjama."},{"v":29,"t":"Ja vam stoga u baštinu predajem kraljevstvo što ga je meni predao moj Otac:"},{"v":30,"t":"da jedete i pijete za mojim stolom u kraljevstvu mojemu i sjedite na prijestoljima sudeći dvanaest plemena Izraelovih.”"},{"v":31,"t":"“Šimune, Šimune, evo Sotona zaiska da vas prorešeta kao pšenicu."},{"v":32,"t":"Ali ja sam molio za tebe da ne malakše tvoja vjera. Pa kad k sebi dođeš, učvrsti svoju braću.”"},{"v":33,"t":"Petar mu reče: “Gospodine, s tobom sam spreman i u tamnicu i u smrt.”"},{"v":34,"t":"A Isus će mu: “Kažem ti, Petre, neće se danas oglasiti pijetao dok triput ne zatajiš da me poznaš.”"},{"v":35,"t":"I reče: “Kad sam vas poslao bez kese i bez torbe i bez sandala, je li vam što nedostajalo?” Oni odgovore: “Ništa.”"},{"v":36,"t":"Nato će im: “No sada tko ima kesu, neka je uzme! Isto tako i torbu! A koji nema, neka proda svoju haljinu i neka kupi sebi mač"},{"v":37,"t":"jer kažem vam, ono što je napisano treba se ispuniti na meni: Među zlikovce bi ubrojen. Uistinu, sve što se odnosi na mene ispunja se.”"},{"v":38,"t":"Oni mu rekoše: “Gospodine, evo ovdje dva mača!” Reče im: “Dosta je!”"},{"v":39,"t":"Tada iziđe te se po običaju zaputi na Maslinsku goru. Za njim pođoše i njegovi učenici."},{"v":40,"t":"Kada dođe onamo, reče im: “Molite da ne padnete u napast!”"},{"v":41,"t":"I otrgnu se od njih koliko bi se kamenom dobacilo, pade na koljena pa se molio:"},{"v":42,"t":"“Oče! Ako hoćeš, otkloni ovu čašu od mene. Ali ne moja volja, nego tvoja neka bude!”"},{"v":43,"t":"A ukaza mu se anđeo s neba koji ga ohrabri. A kad je bio u smrtnoj muci, usrdnije se molio."},{"v":44,"t":"I bijaše znoj njegov kao kaplje krvi koje su padale na zemlju."},{"v":45,"t":"Usta od molitve, dođe učenicima i nađe ih snene od žalosti"},{"v":46,"t":"pa im reče: “Što spavate? Ustanite! Molite da ne padnete u napast!”"},{"v":47,"t":"Dok je on još govorio, eto svjetine, a pred njom jedan od dvanaestorice, zvani Juda. On se približi Isusu da ga poljubi."},{"v":48,"t":"Isus mu reče: “Juda, poljupcem Sina Čovječjeg predaješ?”"},{"v":49,"t":"A oni oko njega, vidjevši što se zbiva, rekoše: “Gospodine, da udarimo mačem?”"},{"v":50,"t":"I jedan od njih udari slugu velikoga svećenika i odsiječe mu desno uho."},{"v":51,"t":"Isus odgovori: “Pustite! Dosta!” Onda se dotače uha i zacijeli ga."},{"v":52,"t":"Nato Isus reče onima koji se digoše na nj, glavarima svećeničkim, zapovjednicima hramskim i starješinama: “Kao na razbojnika iziđoste s mačevima i toljagama!"},{"v":53,"t":"Danomice bijah s vama u Hramu i ne digoste ruke na me. No ovo je vaš čas i vlast Tmina.”"},{"v":54,"t":"Uhvatiše ga dakle, odvedoše i uvedoše u dom velikoga svećenika. Petar je išao za njim izdaleka."},{"v":55,"t":"A posred dvorišta naložiše vatru i posjedaše uokolo. Među njih sjedne Petar."},{"v":56,"t":"Ugleda ga neka sluškinja gdje sjedi kraj vatre, oštro ga pogleda i reče: “I ovaj bijaše s njim!”"},{"v":57,"t":"A on zanijeka: “Ne znam ga, ženo!”"},{"v":58,"t":"Malo zatim opazi ga netko drugi i reče: “I ti si od njih!” A Petar reče: “Čovječe, nisam!”"},{"v":59,"t":"I nakon otprilike jedne ure drugi neki navaljivaše: “Doista, i ovaj bijaše s njim! Ta Galilejac je!”"},{"v":60,"t":"A Petar će: “Čovječe, ne znam što govoriš!” I umah, dok je on još govorio, oglasi se pijetao."},{"v":61,"t":"Gospodin se obazre i upre pogled u Petra, a Petar se spomenu riječi Gospodinove, kako mu ono reče: “Prije nego se danas pijetao oglasi, zatajit ćeš me tri puta.”"},{"v":62,"t":"I iziđe te gorko zaplaka."},{"v":63,"t":"A ljudi koji su Isusa čuvali udarajući ga poigravali se njime"},{"v":64,"t":"i zastirući mu lice, zapitkivali ga: “Proreci tko te udario!”"},{"v":65,"t":"I mnogim se drugim pogrdama nabacivali na nj."},{"v":66,"t":"A kad se razdanilo, sabra se starješinstvo narodno, glavari svećenički i pismoznanci te ga dovedoše pred svoje Vijeće"},{"v":67,"t":"i rekoše: “Ako si ti Krist, reci nam!” A on će im: “Ako vam reknem, nećete vjerovati;"},{"v":68,"t":"ako vas zapitam, nećete odgovoriti."},{"v":69,"t":"No od sada će Sin Čovječji sjedjeti zdesna Sile Božje.”"},{"v":70,"t":"Nato svi rekoše: “Ti si, dakle, Sin Božji!” On im reče: “Vi velite! Ja jesam!”"},{"v":71,"t":"Nato će oni: “Što nam još svjedočanstvo treba? Ta sami smo čuli iz njegovih usta!”"}]},"23":{"fa":[{"v":1,"t":"پس تمام جماعت ایشان برخاسته، اورا نزد پیلاطس بردند."},{"v":2,"t":"و شکایت بر اوآغاز نموده، گفتند: «این شخص را یافته‌ایم که قوم را گمراه می‌کند و از جزیه دادن به قیصر منع می‌نماید و می‌گوید که خود مسیح و پادشاه است.»"},{"v":3,"t":"پس پیلاطس از او پرسیده، گفت: «آیا توپادشاه یهود هستی؟» او در جواب وی گفت: «تومی گویی.»"},{"v":4,"t":"آنگاه پیلاطس به روسای کهنه وجمیع قوم گفت که «در این شخص هیچ عیبی نمی یابم.»"},{"v":5,"t":"ایشان شدت نموده گفتند که «قوم رامی شوراند و در تمام یهودیه از جلیل گرفته تا به اینجا تعلیم می‌دهد.»"},{"v":6,"t":"چون پیلاطس نام جلیل را شنید پرسید که «آیا این مرد جلیلی است؟»"},{"v":7,"t":"و چون مطلع شد که از ولایت هیرودیس است او را نزد وی فرستاد، چونکه هیرودیس در آن ایام در اورشلیم بود."},{"v":8,"t":"اما هیرودیس چون عیسی را دید، بغایت شادگردید زیرا که مدت مدیدی بود می‌خو. است اورا ببیند چونکه شهرت او را بسیار شنیده بود ومترصد می‌بود که معجزه‌ای از او بیند."},{"v":9,"t":"پس چیزهای بسیار از وی پرسید لیکن او به وی هیچ جواب نداد."},{"v":10,"t":"و روسای کهنه و کاتبان حاضرشده به شدت تمام بر وی شکایت می‌نمودند."},{"v":11,"t":"پس هیرودیس با لشکریان خود او را افتضاح نموده و استهزا کرده لباس فاخر بر او پوشانید ونزد پیلاطس او را باز فرستاد."},{"v":12,"t":"و در همان روزپیلاطس و هیرودیس با یکدیگر مصالحه کردند، زیرا قبل از آن در میانشان عداوتی بود."},{"v":13,"t":"پس پیلاطس روسای کهنه و سرادران وقوم را خوانده،"},{"v":14,"t":"به ایشان گفت: «این مرد را نزدمن آوردید که قوم را می‌شوراند. الحال من او رادر حضور شما امتحان کردم و از آنچه بر او ادعامی کنید اثری نیافتم."},{"v":15,"t":"و نه هیرودیس هم زیراکه شما را نزد او فرستادم و اینک هیچ عمل مستوجب قتل از او صادر نشده است."},{"v":16,"t":"پس اورا تنبیه نموده رها خواهم کرد.»"},{"v":17,"t":"زیرا او را لازم بود که هر عیدی کسی را برای ایشان آزاد کند."},{"v":18,"t":"آنگاه همه فریاد کرده، گفتند: «او را هلاک کن وبرابا را برای ما رها فرما.»"},{"v":19,"t":"و او شخصی بود که به‌سبب شورش و قتلی که در شهر واقع شده بود، در زندان افکنده شده بود."},{"v":20,"t":"باز پیلاطس نداکرده خواست که عیسی را رها کند."},{"v":21,"t":"لیکن ایشان فریاد زده گفتند: «او را مصلوب کن، مصلوب کن.»"},{"v":22,"t":"بار سوم به ایشان گفت: «چرا؟ چه بدی کرده است؟ من در او هیچ علت قتل نیافتم. پس او را تادیب کرده رها می‌کنم.»"},{"v":23,"t":"اماایشان به صداهای بلند مبالغه نموده خواستند که مصلوب شود و آوازهای ایشان و روسای کهنه غالب آمد."},{"v":24,"t":"پس پیلاطس فرمود که برحسب خواهش ایشان بشود."},{"v":25,"t":"و آن کس را که به‌سبب شورش و قتل در زندان حبس بود که خواستند رها کرد و عیسی را به خواهش ایشان سپرد."},{"v":26,"t":"و چون او را می‌بردند شمعون قیروانی را که از صحرا می‌آمد مجبور ساخته صلیب را بر اوگذاردند تا از عقب عیسی ببرد."},{"v":27,"t":"و گروهی بسیاراز قوم و زنانی که سینه می‌زدند و برای او ماتم می‌گرفتند، در عقب او افتادند."},{"v":28,"t":"آنگاه عیسی به سوی آن زنان روی گردانیده، گفت: «ای دختران اورشلیم برای من گریه مکنید، بلکه بجهت خود واولاد خود ماتم کنید."},{"v":29,"t":"زیرا اینک ایامی می‌آیدکه در آنها خواهند گفت، خوشابحال نازادگان ورحمهایی که بار نیاوردند و پستانهایی که شیرندادند."},{"v":30,"t":"و در آن هنگام به کوهها خواهند گفت که بر ما بیفتید و به تلها که ما را پنهان کنید."},{"v":31,"t":"زیرااگر این کارها را به چوب تر کردند به چوب خشک چه خواهد شد؟»"},{"v":32,"t":"و دو نفر دیگر را که خطاکار بودند نیزآوردند تا ایشان را با او بکشند."},{"v":33,"t":"و چون به موضعی که آن را کاسه سر می‌گویند رسیدند، اورا در آنجا با آن دو خطاکار، یکی بر طرف راست و دیگری بر چپ او مصلوب کردند."},{"v":34,"t":"عیسی گفت: «ای پدر اینها را بیامرز، زیراکه نمی دانند چه می‌کنند.» پس جامه های او راتقسیم کردند و قرعه افکندند."},{"v":35,"t":"و گروهی به تماشا ایستاده بودند. و بزرگان نیز تمسخرکنان با ایشان می‌گفتند: «دیگران را نجات داد. پس اگر او مسیح و برگزیده خدا می‌باشد خود رابرهاند.»"},{"v":36,"t":"و سپاهیان نیز او را استهزا می‌کردند و آمده او را سرکه می‌دادند،"},{"v":37,"t":"و می‌گفتند: «اگر توپادشاه یهود هستی خود را نجات ده.»"},{"v":38,"t":"و بر سراو تقصیرنامه‌ای نوشتند به خط یونانی و رومی وعبرانی که «این است پادشاه یهود.»"},{"v":39,"t":"و یکی از آن دو خطاکار مصلوب بر وی کفر گفت که «اگر تو مسیح هستی خود را و ما رابرهان.»"},{"v":40,"t":"اما آن دیگری جواب داده، او را نهیب کرد و گفت: «مگر تو از خدا نمی ترسی؟ چونکه تو نیز زیر همین حکمی."},{"v":41,"t":"و اما ما به انصاف، چونکه جزای اعمال خود را یافته‌ایم، لیکن این شخص هیچ کار بی‌جا نکرده است.»"},{"v":42,"t":"پس به عیسی گفت: «ای خداوند، مرا به یاد آور هنگامی که به ملکوت خود آیی.»"},{"v":43,"t":"عیسی به وی گفت: «هرآینه به تو می‌گویم امروز با من در فردوس خواهی بود.»"},{"v":44,"t":"و تخمین از ساعت ششم تا ساعت نهم، ظلمت تمام روی زمین را فرو گرفت."},{"v":45,"t":"وخورشید تاریک گشت و پرده قدس از میان بشکافت."},{"v":46,"t":"و عیسی به آواز بلند صدا زده گفت: «ای پدر به‌دستهای تو روح خود را می‌سپارم.» این را بگفت و جان را تسلیم نمود."},{"v":47,"t":"امایوزباشی چون این ماجرا را دید، خدا را تمجیدکرده، گفت: «در حقیقت، این مرد صالح بود.»"},{"v":48,"t":"وتمامی گروه که برای این تماشا جمع شده بودندچون این وقایع را دیدند، سینه زنان برگشتند."},{"v":49,"t":"و جمیع آشنایان او از دور ایستاده بودند، با زنانی که از جلیل او را متابعت کرده بودند تا این امور راببینند."},{"v":50,"t":"و اینک یوسف نامی از اهل شورا که مردنیکو و صالح بود،"},{"v":51,"t":"که در رای و عمل ایشان مشارکت نداشت و از اهل رامه بلدی از بلاد یهودبود و انتظار ملکوت خدا را می‌کشید،"},{"v":52,"t":"نزدیک پیلاطس آمده جسد عیسی را طلب نمود."},{"v":53,"t":"پس آن را پایین آورده در کتان پیچید و در قبری که ازسنگ تراشیده بود و هیچ‌کس ابد در آن دفن نشده بود سپرد."},{"v":54,"t":"و آن روز تهیه بود و سبت نزدیک می‌شد."},{"v":55,"t":"و زنانی که در عقب او از جلیل آمده بودند از پی او رفتند و قبر و چگونگی گذاشته شدن بدن او را دیدند."},{"v":56,"t":"پس برگشته، حنوط و عطریات مهیا ساختند و روز سبت را به حسب حکم آرام گرفتند."}],"en":[{"v":1,"t":"The whole company of them rose up and brought him before Pilate."},{"v":2,"t":"They began to accuse him, saying, “We found this man perverting the nation, forbidding paying taxes to Caesar, and saying that he himself is Christ, a king.”"},{"v":3,"t":"Pilate asked him, “Are you the King of the Jews?” He answered him, “So you say.”"},{"v":4,"t":"Pilate said to the chief priests and the multitudes, “I find no basis for a charge against this man.”"},{"v":5,"t":"But they insisted, saying, “He stirs up the people, teaching throughout all Judea, beginning from Galilee even to this place.”"},{"v":6,"t":"But when Pilate heard Galilee mentioned, he asked if the man was a Galilean."},{"v":7,"t":"When he found out that he was in Herod’s jurisdiction, he sent him to Herod, who was also in Jerusalem during those days."},{"v":8,"t":"Now when Herod saw Jesus, he was exceedingly glad, for he had wanted to see him for a long time, because he had heard many things about him. He hoped to see some miracle done by him."},{"v":9,"t":"He questioned him with many words, but he gave no answers."},{"v":10,"t":"The chief priests and the scribes stood, vehemently accusing him."},{"v":11,"t":"Herod with his soldiers humiliated him and mocked him. Dressing him in luxurious clothing, they sent him back to Pilate."},{"v":12,"t":"Herod and Pilate became friends with each other that very day, for before that they were enemies with each other."},{"v":13,"t":"Pilate called together the chief priests, the rulers, and the people,"},{"v":14,"t":"and said to them, “You brought this man to me as one that perverts the people, and behold, having examined him before you, I found no basis for a charge against this man concerning those things of which you accuse him."},{"v":15,"t":"Neither has Herod, for I sent you to him, and see, nothing worthy of death has been done by him."},{"v":16,"t":"I will therefore chastise him and release him.”"},{"v":17,"t":"Now he had to release one prisoner to them at the feast."},{"v":18,"t":"But they all cried out together, saying, “Away with this man! Release to us Barabbas!”—"},{"v":19,"t":"one who was thrown into prison for a certain revolt in the city, and for murder."},{"v":20,"t":"Then Pilate spoke to them again, wanting to release Jesus,"},{"v":21,"t":"but they shouted, saying, “Crucify! Crucify him!”"},{"v":22,"t":"He said to them the third time, “Why? What evil has this man done? I have found no capital crime in him. I will therefore chastise him and release him.”"},{"v":23,"t":"But they were urgent with loud voices, asking that he might be crucified. Their voices and the voices of the chief priests prevailed."},{"v":24,"t":"Pilate decreed that what they asked for should be done."},{"v":25,"t":"He released him who had been thrown into prison for insurrection and murder, for whom they asked, but he delivered Jesus up to their will."},{"v":26,"t":"When they led him away, they grabbed one Simon of Cyrene, coming from the country, and laid the cross on him to carry it after Jesus."},{"v":27,"t":"A great multitude of the people followed him, including women who also mourned and lamented him."},{"v":28,"t":"But Jesus, turning to them, said, “Daughters of Jerusalem, don’t weep for me, but weep for yourselves and for your children."},{"v":29,"t":"For behold, the days are coming in which they will say, ‘Blessed are the barren, the wombs that never bore, and the breasts that never nursed.’"},{"v":30,"t":"Then they will begin to tell the mountains, ‘Fall on us!’ and tell the hills, ‘Cover us.’"},{"v":31,"t":"For if they do these things in the green tree, what will be done in the dry?”"},{"v":32,"t":"There were also others, two criminals, led with him to be put to death."},{"v":33,"t":"When they came to the place that is called “The Skull”, they crucified him there with the criminals, one on the right and the other on the left."},{"v":34,"t":"Jesus said, “Father, forgive them, for they don’t know what they are doing.” Dividing his garments among them, they cast lots."},{"v":35,"t":"The people stood watching. The rulers with them also scoffed at him, saying, “He saved others. Let him save himself, if this is the Christ of God, his chosen one!”"},{"v":36,"t":"The soldiers also mocked him, coming to him and offering him vinegar,"},{"v":37,"t":"and saying, “If you are the King of the Jews, save yourself!”"},{"v":38,"t":"An inscription was also written over him in letters of Greek, Latin, and Hebrew: “THIS IS THE KING OF THE JEWS.”"},{"v":39,"t":"One of the criminals who was hanged insulted him, saying, “If you are the Christ, save yourself and us!”"},{"v":40,"t":"But the other answered, and rebuking him said, “Don’t you even fear God, seeing you are under the same condemnation?"},{"v":41,"t":"And we indeed justly, for we receive the due reward for our deeds, but this man has done nothing wrong.”"},{"v":42,"t":"He said to Jesus, “Lord, remember me when you come into your Kingdom.”"},{"v":43,"t":"Jesus said to him, “Assuredly I tell you, today you will be with me in Paradise.”"},{"v":44,"t":"It was now about the sixth hour, and darkness came over the whole land until the ninth hour."},{"v":45,"t":"The sun was darkened, and the veil of the temple was torn in two."},{"v":46,"t":"Jesus, crying with a loud voice, said, “Father, into your hands I commit my spirit!” Having said this, he breathed his last."},{"v":47,"t":"When the centurion saw what was done, he glorified God, saying, “Certainly this was a righteous man.”"},{"v":48,"t":"All the multitudes that came together to see this, when they saw the things that were done, returned home beating their chests."},{"v":49,"t":"All his acquaintances and the women who followed with him from Galilee stood at a distance, watching these things."},{"v":50,"t":"Behold, there was a man named Joseph, who was a member of the council, a good and righteous man"},{"v":51,"t":"(he had not consented to their counsel and deed), from Arimathaea, a city of the Jews, who was also waiting for God’s Kingdom."},{"v":52,"t":"This man went to Pilate, and asked for Jesus’ body."},{"v":53,"t":"He took it down and wrapped it in a linen cloth, and laid him in a tomb that was cut in stone, where no one had ever been laid."},{"v":54,"t":"It was the day of the Preparation, and the Sabbath was drawing near."},{"v":55,"t":"The women who had come with him out of Galilee followed after, and saw the tomb and how his body was laid."},{"v":56,"t":"They returned and prepared spices and ointments. On the Sabbath they rested according to the commandment."}],"hr":[{"v":1,"t":"I ustade sva ona svjetina. Odvedoše ga Pilatu"},{"v":2,"t":"i stadoše ga optuživati: “Ovoga nađosmo kako zavodi naš narod i brani davati caru porez te za sebe tvrdi da je Krist, kralj.”"},{"v":3,"t":"Pilat ga upita: “Ti li si kralj židovski?” On mu odgovori: “Ti kažeš!”"},{"v":4,"t":"Tada Pilat reče glavarima svećeničkim i svjetini: “Nikakve krivnje ne nalazim na ovom čovjeku!”"},{"v":5,"t":"No oni navaljivahu: “Buni narod naučavajući po svoj Judeji, počevši od Galileje pa dovde!”"},{"v":6,"t":"Čuvši to, Pilat propita da li je taj čovjek Galilejac."},{"v":7,"t":"Saznavši da je iz oblasti Herodove, posla ga Herodu, koji i sam bijaše onih dana u Jeruzalemu."},{"v":8,"t":"A kad Herod ugleda Isusa, veoma se obradova jer ga je već odavna želo vidjeti zbog onoga što je o njemu slušao te se nadao od njega vidjeti koje čudo."},{"v":9,"t":"Postavljao mu je mnoga pitanja, ali mu Isus uopće nije odgovarao."},{"v":10,"t":"A stajahu ondje i glavari svećenički i pismoznanci optužujući ga žestoko."},{"v":11,"t":"Herod ga zajedno sa svojom vojskom prezre i ismija: obuče ga u bijelu haljinu i posla natrag Pilatu."},{"v":12,"t":"Onoga se dana Herod i Pilat sprijateljiše, jer prije bijahu neprijatelji."},{"v":13,"t":"A Pilat dade sazvati glavare svećeničke, vijećnike i narod"},{"v":14,"t":"te im reče: “Doveli ste mi ovoga čovjeka kao da buni narod. Ja ga evo ispitah pred vama pa ne nađoh na njemu ni jedne krivice za koju ga optužujete."},{"v":15,"t":"A ni Herod jer ga posla natrag nama. Evo, on nije počinio ništa čime bi zaslužio smrt."},{"v":16,"t":"Kaznit ću ga dakle i pustiti.”"},{"v":17,"t":"#"},{"v":18,"t":"I povikaše svi uglas: “Smakni ovoga, a pusti nam Barabu!”"},{"v":19,"t":"A taj bijaše bačen u tamnicu zbog neke pobune u gradu i ubojstva."},{"v":20,"t":"Pilat im stoga ponovno progovori hoteći osloboditi Isusa."},{"v":21,"t":"Ali oni vikahu: “Raspni, raspni ga!”"},{"v":22,"t":"On im treći put reče: “Ta što je on zla učinio? Ne nađoh na njemu smrtne krivice. Kaznit ću ga dakle i pustiti.”"},{"v":23,"t":"Ali oni navaljivahu iza glasa ištući da se razapne. I vika im bivala sve jača."},{"v":24,"t":"Pilat presudi da im bude što ištu."},{"v":25,"t":"Pusti onoga koji zbog pobune i ubojstva bijaše bačen u tamnicu, koga su iskali, a Isusa preda njima na volju."},{"v":26,"t":"Kad ga odvedoše, uhvatiše nekog Šimuna Cirenca koji je dolazio s polja i stave na nj križ da ga nosi za Isusom."},{"v":27,"t":"Za njim je išlo silno mnoštvo svijeta, napose žena, koje su plakale i naricale za njim."},{"v":28,"t":"Isus se okrenu prema njima pa im reče: “Kćeri Jeruzalemske, ne plačite nada mnom, nego plačite nad sobom i nad djecom svojom."},{"v":29,"t":"Jer evo idu dani kad će se govoriti: 'Blago nerotkinjama, utrobama koje ne rodiše i sisama koje ne dojiše.'"},{"v":30,"t":"Tad će početi govoriti gorama: 'Padnite na nas!' i bregovima: 'Pokrijte nas!'"},{"v":31,"t":"Jer ako se tako postupa sa zelenim stablom, što li će biti sa suhim?”"},{"v":32,"t":"A vodili su i drugu dvojicu, zločince, da ih s njime pogube."},{"v":33,"t":"I kada dođoše na mjesto zvano Lubanja, ondje razapeše njega i te zločince, jednoga zdesna, drugoga slijeva."},{"v":34,"t":"A Isus je govorio: “Oče, oprosti im, ne znaju što čine!” I razdijeliše među se haljine njegove bacivši kocke."},{"v":35,"t":"Stajao je ondje narod i promatrao. A podrugivali se i glavari govoreći: “Druge je spasio, neka spasi sam sebe ako je on Krist Božji, Izabranik!”"},{"v":36,"t":"Izrugivali ga i vojnici, prilazili mu i nudili ga octom"},{"v":37,"t":"govoreći: “Ako si ti kralj židovski, spasi sam sebe!”"},{"v":38,"t":"A bijaše i natpis ponad njega: “Ovo je kralj židovski.”"},{"v":39,"t":"Jedan ga je od obješenih zločinaca pogrđivao: “Nisi li ti Krist? Spasi sebe i nas!”"},{"v":40,"t":"A drugi ovoga prekoravaše: “Zar se ne bojiš Boga ni ti, koji si pod istom osudom?"},{"v":41,"t":"Ali mi po pravdi jer primamo što smo djelima zaslužili, a on - on ništa opako ne učini.”"},{"v":42,"t":"Onda reče: “Isuse, sjeti me se kada dođeš u kraljevstvo svoje.”"},{"v":43,"t":"A on će mu: “Zaista ti kažem: danas ćeš biti sa mnom u raju!”"},{"v":44,"t":"Bijaše već oko šeste ure kad nasta tama po svoj zemlji - sve do ure devete,"},{"v":45,"t":"jer sunce pomrča, a hramska se zavjesa razdrije po sredini."},{"v":46,"t":"I povika Isus iza glasa: “Oče, u ruke tvoje predajem duh svoj!” To rekavši, izdahnu."},{"v":47,"t":"Kad satnik vidje što se zbiva, stane slaviti Boga: “Zbilja, čovjek ovaj bijaše pravednik!”"},{"v":48,"t":"I kad je sav svijet koji se zgrnuo na taj prizor vidio što se zbiva, vraćao se bijući se u prsa."},{"v":49,"t":"Stajahu podalje i gledahu to svi znanci njegovi i žene koje su za njim išle iz Galileje."},{"v":50,"t":"I dođe čovjek imenom Josip, vijećnik, čovjek čestit i pravedan;"},{"v":51,"t":"on ne privoli njihovoj odluci i postupku. Bijaše iz Arimateje, grada judejskoga i iščekivaše kraljevstvo Božje."},{"v":52,"t":"Taj dakle pristupi Pilatu i zaiska tijelo Isusovo."},{"v":53,"t":"Zatim ga skinu, povi u platno i položi u grob isklesan u koji još ne bijaše nitko položen."},{"v":54,"t":"Bijaše dan Priprave; subota je svitala."},{"v":55,"t":"A pratile to žene koje su s Isusom došle iz Galileje: motrile grob i kako je položeno tijelo njegovo."},{"v":56,"t":"Zatim se vrate i priprave miomirise i pomasti. U subotu mirovahu po propisu."}]},"24":{"fa":[{"v":1,"t":"پس در روز اول هفته هنگام سپیده صبح، حنوطی را که درست کرده بودندبا خود برداشته به‌سر قبر‌آمدند و بعضی دیگران همراه ایشان."},{"v":2,"t":"و سنگ را از سر قبر غلطانیده دیدند."},{"v":3,"t":"چون داخل شدند، جسد خداوند عیسی را نیافتند"},{"v":4,"t":"و واقع شد هنگامی که ایشان از این امر متحیر بودند که ناگاه دو مرد در لباس درخشنده نزد ایشان بایستادند."},{"v":5,"t":"و چون ترسان شده سرهای خود را به سوی زمین افکنده بودند، به ایشان گفتند: «چرا زنده را از میان مردگان می‌طلبید؟"},{"v":6,"t":"در اینجا نیست، بلکه برخاسته است. به یاد آورید که چگونه وقتی که در جلیل بود شمارا خبر داده،"},{"v":7,"t":"گفت ضروری است که پسر انسان به‌دست مردم گناهکار تسلیم شده مصلوب گرددو روز سوم برخیزد.»"},{"v":8,"t":"پس سخنان او را به‌خاطرآوردند."},{"v":9,"t":"و از سر قبر برگشته، آن یازده و دیگران را ازهمه این امور مطلع ساختند."},{"v":10,"t":"و مریم مجدلیه ویونا و مریم مادر یعقوب و دیگر رفقای ایشان بودند که رسولان را از این چیزها مطلع ساختند."},{"v":11,"t":"لیکن سخنان زنان را هذیان پنداشته باورنکردند."},{"v":12,"t":"اما پطرس برخاسته، دوان دوان به سوی قبر رفت و خم شده کفن را تنها گذاشته دیدو از این ماجرا در عجب شده به خانه خود رفت."},{"v":13,"t":"و اینک در همان روز دو نفر از ایشان می‌رفتند به سوی قریه‌ای که از اورشلیم به مسافت، شصت تیر پرتاب دور بود و عمواس نام داشت."},{"v":14,"t":"و با یک دیگر از تمام این وقایع گفتگومی کردند."},{"v":15,"t":"و چون ایشان در مکالمه و مباحثه می‌بودند، ناگاه خود عیسی نزدیک شده، با ایشان همراه شد."},{"v":16,"t":"ولی چشمان ایشان بسته شد تا اورا نشناسند."},{"v":17,"t":"او به ایشان گفت: «چه حرفها است که با یکدیگر می‌زنید و راه را به کدورت می‌پیمایید؟»"},{"v":18,"t":"یکی که کلیوپاس نام داشت درجواب وی گفت: «مگر تو در اورشلیم غریب وتنها هستی و از آنچه در این ایام در اینجا واقع شدواقف نیستی؟»"},{"v":19,"t":"به ایشان گفت: «چه چیزاست؟» گفتندش: «درباره عیسی ناصری که مردی بود نبی و قادر در فعل و قول در حضورخدا و تمام قوم،"},{"v":20,"t":"و چگونه روسای کهنه وحکام ما او را به فتوای قتل سپردند و او رامصلوب ساختند."},{"v":21,"t":"اما ما امیدوار بودیم که همین است آنکه می‌باید اسرائیل را نجات دهد وعلاوه بر این همه، امروز از وقوع این امور روزسوم است،"},{"v":22,"t":"و بعضی از زنان ما هم ما را به حیرت انداختند که بامدادان نزد قبر رفتند،"},{"v":23,"t":"وجسد او را نیافته آمدند و گفتند که فرشتگان را دررویا دیدیم که گفتند او زنده شده است."},{"v":24,"t":"وجمعی از رفقای ما به‌سر قبر رفته، آن چنانکه زنان گفته بودند یافتند لیکن او را ندیدند.»"},{"v":25,"t":"او به ایشان گفت: «ای بی‌فهمان وسست دلان از ایمان آوردن به انچه انبیا گفته‌اند."},{"v":26,"t":"آیا نمی بایست که مسیح این زحمات را بیند تابه جلال خود برسد؟»"},{"v":27,"t":"پس از موسی و سایرانبیا شروع کرده، اخبار خود را در تمام کتب برای ایشان شرح فرمود."},{"v":28,"t":"و چون به آن دهی که عازم آن بودندرسیدند، او قصد نمود که دورتر رود."},{"v":29,"t":"و ایشان الحاح کرده، گفتند که «با ما باش. چونکه شب نزدیک است و روز به آخر رسیده.» پس داخل گشته با ایشان توقف نمود."},{"v":30,"t":"و چون با ایشان نشسته بود نان را گرفته برکت داد و پاره کرده به ایشان داد."},{"v":31,"t":"که ناگاه چشمانشان باز شده، او راشناختند و در ساعت از ایشان غایب شد."},{"v":32,"t":"پس با یکدیگر گفتند: «آیا دل در درون مانمی سوخت، وقتی که در راه با ما تکلم می‌نمود وکتب را بجهت ما تفسیر می‌کرد؟»"},{"v":33,"t":"و در آن ساعت برخاسته به اورشلیم مراجعت کردند و آن یازده را یافتند که با رفقای خود جمع شده"},{"v":34,"t":"می گفتند: «خداوند در حقیقت برخاسته و به شمعون ظاهر شده است.»"},{"v":35,"t":"و آن دو نفر نیز ازسرگذشت راه و کیفیت شناختن او هنگام پاره کردن نان خبر دادند."},{"v":36,"t":"و ایشان در این گفتگو می‌بودند که ناگاه عیسی خود در میان ایشان ایستاده، به ایشان گفت: «سلام بر شما باد.»"},{"v":37,"t":"اما ایشان لرزان وترسان شده گمان بردند که روحی می‌بینند."},{"v":38,"t":"به ایشان گفت: «چرا مضطرب شدید و برای چه دردلهای شما شبهات روی می‌دهد؟"},{"v":39,"t":"دستها وپایهایم را ملاحظه کنید که من خود هستم و دست بر من گذارده ببینید، زیرا که روح گوشت واستخوان ندارد، چنانکه می‌نگرید که در من است.»"},{"v":40,"t":"این را گفت و دستها و پایهای خود رابدیشان نشان داد."},{"v":41,"t":"و چون ایشان هنوز ازخوشی تصدیق نکرده، در عجب مانده بودند، به ایشان گفت: «چیز خوراکی در اینجا دارید؟»"},{"v":42,"t":"پس قدری از ماهی بریان و از شانه عسل به وی دادند."},{"v":43,"t":"پس آن را گرفته پیش ایشان بخورد."},{"v":44,"t":"و به ایشان گفت: «همین است سخنانی که وقتی با شما بودم گفتم ضروری است که آنچه درتورات موسی و صحف انبیا و زبور درباره من مکتوب است به انجام رسد.»"},{"v":45,"t":"و در آن وقت ذهن ایشان را روشن کرد تا کتب را بفهمند."},{"v":46,"t":"و به ایشان گفت: «بر همین منوال مکتوب است وبدینطور سزاوار بود که مسیح زحمت کشد و روزسوم از مردگان برخیزد."},{"v":47,"t":"و از اورشلیم شروع کرده، موعظه به توبه و آمرزش گناهان در همه امت‌ها به نام او کرده شود."},{"v":48,"t":"و شما شاهد بر این امور هستید."},{"v":49,"t":"و اینک، من موعود پدر خود را برشما می‌فرستم. پس شما در شهر اورشلیم بمانیدتا وقتی که به قوت از اعلی آراسته شوید.»"},{"v":50,"t":"پس ایشان را بیرون از شهر تا بیت عنیا بردو دستهای خود را بلند کرده، ایشان را برکت داد."},{"v":51,"t":"و چنین شد که در حین برکت دادن ایشان، ازایشان جدا گشته، به سوی آسمان بالا برده شد."},{"v":52,"t":"پس او را پرستش کرده، با خوشی عظیم به سوی اورشلیم برگشتند."},{"v":53,"t":"و پیوسته درهیکل مانده، خدا را حمد و سپاس می‌گفتند. آمین."}],"en":[{"v":1,"t":"But on the first day of the week, at early dawn, they and some others came to the tomb, bringing the spices which they had prepared."},{"v":2,"t":"They found the stone rolled away from the tomb."},{"v":3,"t":"They entered in, and didn’t find the Lord Jesus’ body."},{"v":4,"t":"While they were greatly perplexed about this, behold, two men stood by them in dazzling clothing."},{"v":5,"t":"Becoming terrified, they bowed their faces down to the earth. The men said to them, “Why do you seek the living among the dead?"},{"v":6,"t":"He isn’t here, but is risen. Remember what he told you when he was still in Galilee,"},{"v":7,"t":"saying that the Son of Man must be delivered up into the hands of sinful men and be crucified, and the third day rise again?”"},{"v":8,"t":"They remembered his words,"},{"v":9,"t":"returned from the tomb, and told all these things to the eleven and to all the rest."},{"v":10,"t":"Now they were Mary Magdalene, Joanna, and Mary the mother of James. The other women with them told these things to the apostles."},{"v":11,"t":"These words seemed to them to be nonsense, and they didn’t believe them."},{"v":12,"t":"But Peter got up and ran to the tomb. Stooping and looking in, he saw the strips of linen lying by themselves, and he departed to his home, wondering what had happened."},{"v":13,"t":"Behold, two of them were going that very day to a village named Emmaus, which was sixty stadia from Jerusalem."},{"v":14,"t":"They talked with each other about all of these things which had happened."},{"v":15,"t":"While they talked and questioned together, Jesus himself came near, and went with them."},{"v":16,"t":"But their eyes were kept from recognizing him."},{"v":17,"t":"He said to them, “What are you talking about as you walk, and are sad?”"},{"v":18,"t":"One of them, named Cleopas, answered him, “Are you the only stranger in Jerusalem who doesn’t know the things which have happened there in these days?”"},{"v":19,"t":"He said to them, “What things?” They said to him, “The things concerning Jesus the Nazarene, who was a prophet mighty in deed and word before God and all the people;"},{"v":20,"t":"and how the chief priests and our rulers delivered him up to be condemned to death, and crucified him."},{"v":21,"t":"But we were hoping that it was he who would redeem Israel. Yes, and besides all this, it is now the third day since these things happened."},{"v":22,"t":"Also, certain women of our company amazed us, having arrived early at the tomb;"},{"v":23,"t":"and when they didn’t find his body, they came saying that they had also seen a vision of angels, who said that he was alive."},{"v":24,"t":"Some of us went to the tomb and found it just like the women had said, but they didn’t see him.”"},{"v":25,"t":"He said to them, “Foolish people, and slow of heart to believe in all that the prophets have spoken!"},{"v":26,"t":"Didn’t the Christ have to suffer these things and to enter into his glory?”"},{"v":27,"t":"Beginning from Moses and from all the prophets, he explained to them in all the Scriptures the things concerning himself."},{"v":28,"t":"They came near to the village where they were going, and he acted like he would go further."},{"v":29,"t":"They urged him, saying, “Stay with us, for it is almost evening, and the day is almost over.” He went in to stay with them."},{"v":30,"t":"When he had sat down at the table with them, he took the bread and gave thanks. Breaking it, he gave it to them."},{"v":31,"t":"Their eyes were opened and they recognized him; then he vanished out of their sight."},{"v":32,"t":"They said to one another, “Weren’t our hearts burning within us while he spoke to us along the way, and while he opened the Scriptures to us?”"},{"v":33,"t":"They rose up that very hour, returned to Jerusalem, and found the eleven gathered together, and those who were with them,"},{"v":34,"t":"saying, “The Lord is risen indeed, and has appeared to Simon!”"},{"v":35,"t":"They related the things that happened along the way, and how he was recognized by them in the breaking of the bread."},{"v":36,"t":"As they said these things, Jesus himself stood among them, and said to them, “Peace be to you.”"},{"v":37,"t":"But they were terrified and filled with fear, and supposed that they had seen a spirit."},{"v":38,"t":"He said to them, “Why are you troubled? Why do doubts arise in your hearts?"},{"v":39,"t":"See my hands and my feet, that it is truly me. Touch me and see, for a spirit doesn’t have flesh and bones, as you see that I have.”"},{"v":40,"t":"When he had said this, he showed them his hands and his feet."},{"v":41,"t":"While they still didn’t believe for joy, and wondered, he said to them, “Do you have anything here to eat?”"},{"v":42,"t":"They gave him a piece of a broiled fish and some honeycomb."},{"v":43,"t":"He took them, and ate in front of them."},{"v":44,"t":"He said to them, “This is what I told you while I was still with you, that all things which are written in the law of Moses, the prophets, and the psalms concerning me must be fulfilled.”"},{"v":45,"t":"Then he opened their minds, that they might understand the Scriptures."},{"v":46,"t":"He said to them, “Thus it is written, and thus it was necessary for the Christ to suffer and to rise from the dead the third day,"},{"v":47,"t":"and that repentance and remission of sins should be preached in his name to all the nations, beginning at Jerusalem."},{"v":48,"t":"You are witnesses of these things."},{"v":49,"t":"Behold, I send out the promise of my Father on you. But wait in the city of Jerusalem until you are clothed with power from on high.”"},{"v":50,"t":"He led them out as far as Bethany, and he lifted up his hands and blessed them."},{"v":51,"t":"While he blessed them, he withdrew from them and was carried up into heaven."},{"v":52,"t":"They worshiped him and returned to Jerusalem with great joy,"},{"v":53,"t":"and were continually in the temple, praising and blessing God. Amen."}],"hr":[{"v":1,"t":"Prvoga dana u tjednu, veoma rano, dođoše one na grob s miomirisima što ih pripraviše."},{"v":2,"t":"Kamen nađoše otkotrljan od groba."},{"v":3,"t":"Uđoše, ali ne nađoše tijela Gospodina Isusa."},{"v":4,"t":"I dok su stajale zbunjene nad tim, gle, dva čovjeka u blistavoj odjeći stadoše do njih."},{"v":5,"t":"Zastrašene obore lica k zemlji, a oni će im: “Što tražite Živoga među mrtvima?"},{"v":6,"t":"Nije ovdje, nego uskrsnu! Sjetite se kako vam je govorio dok je još bio u Galileji:"},{"v":7,"t":"'Treba da Sin Čovječji bude predan u ruke grešnika, i raspet, i treći dan da ustane.'”"},{"v":8,"t":"I sjetiše se one riječi njegovih,"},{"v":9,"t":"vratiše se s groba te javiše sve to jedanaestorici i svima drugima."},{"v":10,"t":"A bile su to: Marija Magdalena, Ivana i Marija Jakovljeva. I ostale zajedno s njima govorahu to apostolima,"},{"v":11,"t":"ali njima se te riječi pričiniše kao tlapnja, te im ne vjerovahu."},{"v":12,"t":"A Petar usta i potrča na grob. Sagnuvši se, opazi samo povoje. I vrati se kući čudeći se tome što se zbilo."},{"v":13,"t":"I gle, dvojica su od njih toga istog dana putovala u selo koje se zove Emaus, udaljeno od Jeruzalema šezdeset stadija."},{"v":14,"t":"Razgovarahu međusobno o svemu što se dogodilo."},{"v":15,"t":"I dok su tako razgovarali i raspravljali, približi im se Isus i pođe s njima."},{"v":16,"t":"Ali prepoznati ga - bijaše uskraćeno njihovim očima."},{"v":17,"t":"On ih upita: “Što to putem pretresate među sobom?” Oni se snuždeni zaustave"},{"v":18,"t":"te mu jedan od njih, imenom Kleofa, odgovori: “Zar si ti jedini stranac u Jeruzalemu te ne znaš što se u njemu dogodilo ovih dana?”"},{"v":19,"t":"A on će: “Što to?” Odgovore mu: “Pa ono s Isusom Nazarećaninom, koji bijaše prorok - silan na djelu i na riječi pred Bogom i svim narodom:"},{"v":20,"t":"kako su ga glavari svećenički i vijećnici naši predali da bude osuđen na smrt te ga razapeli."},{"v":21,"t":"A mi se nadasmo da je on onaj koji ima otkupiti Izraela. Ali osim svega toga ovo je već treći dan što se to dogodilo."},{"v":22,"t":"A zbuniše nas i žene neke od naših: u praskozorje bijahu na grobu,"},{"v":23,"t":"ali nisu našle njegova tijela pa dođoše te rekoše da su im se ukazali anđeli koji su rekli da je on živ."},{"v":24,"t":"Odoše nato i neki naši na grob i nađoše kako žene rekoše, ali njega ne vidješe.”"},{"v":25,"t":"A on će im: “O bezumni i srca spora da vjerujete što god su proroci navijestili!"},{"v":26,"t":"Nije li trebalo da Krist sve to pretrpi te uđe u svoju slavu?”"},{"v":27,"t":"Počevši tada od Mojsija i svih proroka, protumači im što u svim Pismima ima o njemu."},{"v":28,"t":"Uto se približe selu kamo su išli, a on kao da htjede dalje."},{"v":29,"t":"No oni navaljivahu: “Ostani s nama jer zamalo će večer i dan je na izmaku!” I uniđe da ostane s njima."},{"v":30,"t":"Dok bijaše s njima za stolom, uze kruh, izreče blagoslov, razlomi te im davaše."},{"v":31,"t":"Uto im se otvore oči te ga prepoznaše, a on im iščeznu s očiju."},{"v":32,"t":"Tada rekoše jedan drugome: “Nije li gorjelo srce u nama dok nam je putem govorio, dok nam je otkrivao Pisma?”"},{"v":33,"t":"U isti se čas digoše i vratiše u Jeruzalem. Nađoše okupljenu jedanaestoricu i one koji bijahu s njima."},{"v":34,"t":"Oni im rekoše: “Doista uskrsnu Gospodin i ukaza se Šimunu!”"},{"v":35,"t":"Nato oni pripovjede ono s puta i kako ga prepoznaše u lomljenju kruha."},{"v":36,"t":"Dok su oni o tom razgovarali, stane Isus posred njih i reče im: “Mir vama!”"},{"v":37,"t":"Oni, zbunjeni i prestrašeni, pomisliše da vide duha."},{"v":38,"t":"Reče im Isus: “Zašto se prepadoste? Zašto vam sumnje obuzimaju srce?"},{"v":39,"t":"Pogledajte ruke moje i noge! Ta ja sam! Opipajte me i vidite jer duh tijela ni kostiju nema kao što vidite da ja imam.”"},{"v":40,"t":"Rekavši to, pokaza im ruke i noge."},{"v":41,"t":"I dok oni od radosti još nisu vjerovali, nego se čudom čudili, on im reče: “Imate li ovdje što za jelo?”"},{"v":42,"t":"Oni mu pruže komad pečene ribe."},{"v":43,"t":"On uzme i pred njima pojede."},{"v":44,"t":"Nato im reče: “To je ono što sam vam govorio dok sam još bio s vama: treba da se ispuni sve što je u Mojsijevu Zakonu, u Prorocima i Psalmima o meni napisano.”"},{"v":45,"t":"Tada im otvori pamet da razumiju Pisma"},{"v":46,"t":"te im reče: “Ovako je pisano: 'Krist će trpjeti i treći dan ustati od mrtvih,"},{"v":47,"t":"i u njegovo će se ime propovijedati obraćenje i otpuštenje grijeha po svim narodima počevši od Jeruzalema.'"},{"v":48,"t":"Vi ste tomu svjedoci."},{"v":49,"t":"I evo, ja šaljem na vas Obećanje Oca svojega. Ostanite zato u gradu dok se ne obučete u Silu odozgor.”"},{"v":50,"t":"Zatim ih izvede do Betanije, podiže ruke pa ih blagoslovi."},{"v":51,"t":"I dok ih blagoslivljaše, rasta se od njih i uznesen bi na nebo."},{"v":52,"t":"Oni mu se ničice poklone pa se s velikom radosti vrate u Jeruzalem"},{"v":53,"t":"te sve vrijeme u Hramu blagoslivljahu Boga."}]}},"JHN":{"1":{"fa":[{"v":1,"t":"در ابتدا کلمه بود و کلمه نزد خدا بود وکلمه خدا بود."},{"v":2,"t":"همان در ابتدا نزد خدا بود."},{"v":3,"t":"همه‌چیز به واسطه او آفریده شد و به غیر از اوچیزی از موجودات وجود نیافت."},{"v":4,"t":"در او حیات بود و حیات نور انسان بود."},{"v":5,"t":"و نور در تاریکی می‌درخشد و تاریکی آن را درنیافت."},{"v":6,"t":"شخصی از جانب خدا فرستاده شد که اسمش یحیی بود؛"},{"v":7,"t":"او برای شهادت آمد تا بر نورشهادت دهد تا همه به وسیله او ایمان آورند."},{"v":8,"t":"اوآن نور نبود بلکه آمد تا بر نور شهادت دهد."},{"v":9,"t":"آن نور حقیقی بود که هر انسان را منور می‌گرداند ودر جهان آمدنی بود."},{"v":10,"t":"او در جهان بود و جهان به واسطه او آفریده شد و جهان او را نشناخت."},{"v":11,"t":"به نزد خاصان خود آمد و خاصانش او را نپذیرفتند؛"},{"v":12,"t":"و اما به آن کسانی که او را قبول کردند قدرت داد تا فرزندان خدا گردند، یعنی به هر‌که به اسم اوایمان آورد،"},{"v":13,"t":"که نه از خون و نه از خواهش جسد و نه از خواهش مردم، بلکه از خدا تولدیافتند."},{"v":14,"t":"و کلمه جسم گردید و میان ما ساکن شد، پراز فیض و راستی و جلال او را دیدیم، جلالی شایسته پسر یگانه پدر."},{"v":15,"t":"و یحیی بر او شهادت داد و ندا کرده، می‌گفت: «این است آنکه درباره اوگفتم آنکه بعد از من می‌آید، پیش از من شده است زیرا که بر من مقدم بود.»"},{"v":16,"t":"و از پری او جمیع ما بهره یافتیم و فیض به عوض فیض،"},{"v":17,"t":"زیراشریعت به وسیله موسی عطا شد، اما فیض وراستی به وسیله عیسی مسیح رسید."},{"v":18,"t":"خدا راهرگز کسی ندیده است؛ پسر یگانه‌ای که درآغوش پدر است، همان او را ظاهر کرد."},{"v":19,"t":"و این است شهادت یحیی در وقتی که یهودیان از اورشلیم کاهنان و لاویان را فرستادندتا از او سوال کنند که تو کیستی،"},{"v":20,"t":"که معترف شدو انکار ننمود، بلکه اقرار کرد که من مسیح نیستم."},{"v":21,"t":"آنگاه از او سوال کردند: «پس چه؟ آیا توالیاس هستی؟ گفت: «نیستم.»"},{"v":22,"t":"آنگاه بدو گفتند: «پس کیستی تا به آن کسانی که ما را فرستادند جواب بریم؟ درباره خود چه می‌گویی؟»"},{"v":23,"t":"گفت: «من صدای ندا کننده‌ای دربیابانم که راه خداوند را راست کنید، چنانکه اشعیانبی گفت.»"},{"v":24,"t":"و فرستادگان از فریسیان بودند."},{"v":25,"t":"پس از اوسوال کرده، گفتند: «اگر تو مسیح و الیاس و آن نبی نیستی، پس برای چه تعمید می‌دهی؟»"},{"v":26,"t":"یحیی در جواب ایشان گفت: «من به آب تعمیدمی دهم و در میان شما کسی ایستاده است که شمااو را نمی شناسید."},{"v":27,"t":"و او آن است که بعد از من می آید، اما پیش از من شده است، که من لایق آن نیستم که بند نعلینش را باز کنم.»"},{"v":28,"t":"و این دربیت عبره که آن طرف اردن است، در جایی که یحیی تعمید می‌داد واقع گشت."},{"v":29,"t":"و در فردای آن روز یحیی عیسی را دید که به‌جانب او می‌آید. پس گفت: «اینک بره خدا که گناه جهان را برمی دارد!"},{"v":30,"t":"این است آنکه من درباره او گفتم که مردی بعد از من می‌آید که پیش از من شده است زیرا که بر من مقدم بود."},{"v":31,"t":"و من اورا نشناختم، لیکن تا او به اسرائیل ظاهر گردد، برای همین من آمده به آب تعمید می‌دادم.»"},{"v":32,"t":"پس یحیی شهادت داده، گفت: «روح را دیدم که مثل کبوتری از آسمان نازل شده، بر او قرارگرفت."},{"v":33,"t":"و من او را نشناختم، لیکن او که مرافرستاد تا به آب تعمید دهم، همان به من گفت برهر کس بینی که روح نازل شده، بر او قرار گرفت، همان است او که به روح‌القدس تعمید می‌دهد."},{"v":34,"t":"و من دیده شهادت می‌دهم که این است پسرخدا.»"},{"v":35,"t":"و در روز بعد نیز یحیی با دو نفر از شاگردان خود ایستاده بود."},{"v":36,"t":"ناگاه عیسی را دید که راه می‌رود؛ و گفت: «اینک بره خدا.»"},{"v":37,"t":"و چون آن دو شاگرد کلام او را شنیدند، از پی عیسی روانه شدند."},{"v":38,"t":"پس عیسی روی گردانیده، آن دو نفر رادید که از عقب می‌آیند. بدیشان گفت:"},{"v":39,"t":"«چه می‌خواهید؟» بدو گفتند: «ربی (یعنی‌ای معلم )در کجا منزل می‌نمایی؟»"},{"v":40,"t":"بدیشان گفت: «بیایید و ببینید.» آنگاه آمده، دیدند که کجا منزل دارد، و آن روز را نزد او بماندند و قریب به ساعت دهم بود."},{"v":41,"t":"و یکی از آن دو که سخن یحیی را شنیده، پیروی او نمودند، اندریاس برادر شمعون پطرس بود."},{"v":42,"t":"او اول برادر خود شمعون را یافته، به اوگفت: «مسیح را (که ترجمه آن کرستس است )یافتیم.» و چون او را نزد عیسی آورد، عیسی بدونگریسته، گفت: «تو شمعون پسر یونا هستی؛ واکنون کیفا خوانده خواهی شد (که ترجمه آن پطرس است ).»"},{"v":43,"t":"بامدادان چون عیسی خواست به سوی جلیل روانه شود، فیلپس را یافته، بدو گفت: «ازعقب من بیا.»"},{"v":44,"t":"و فیلپس از بیت صیدا از شهراندریاس وپطرس بود."},{"v":45,"t":"فیلیپس نتنائیل را یافته، بدو گفت: «آن کسی را که موسی در تورات و انبیامذکور داشته‌اند، یافته‌ایم که عیسی پسر یوسف ناصری است.»"},{"v":46,"t":"نتنائیل بدو گفت: «مگرمی شود که از ناصره چیزی خوب پیدا شود؟» فیلپس بدو گفت: «بیا و ببین.»"},{"v":47,"t":"و عیسی چون دید که نتنائیل به سوی او می‌آید، درباره اوگفت: «اینک اسرائیلی حقیقی که در او مکری نیست.»"},{"v":48,"t":"نتنائیل بدو گفت: «مرا از کجامی شناسی؟» عیسی در جواب وی گفت: «قبل ازآنکه فیلپس تو را دعوت کند، در حینی که زیردرخت انجیر بودی تو را دیدم.»"},{"v":49,"t":"نتنائیل درجواب او گفت: «ای استاد تو پسر خدایی! توپادشاه اسرائیل هستی!»"},{"v":50,"t":"عیسی در جواب اوگفت: «آیا از اینکه به تو گفتم که تو را زیر درخت انجیر دیدم، ایمان آوردی؟ بعد از این چیزهای بزرگتر از این خواهی دید.»"},{"v":51,"t":"پس بدو گفت: «آمین آمین به شما می‌گویم که از کنون آسمان را گشاده، و فرشتگان خدا را که بر پسر انسان صعودو نزول می‌کنند خواهید دید.»"}],"en":[{"v":1,"t":"In the beginning was the Word, and the Word was with God, and the Word was God."},{"v":2,"t":"The same was in the beginning with God."},{"v":3,"t":"All things were made through him. Without him, nothing was made that has been made."},{"v":4,"t":"In him was life, and the life was the light of men."},{"v":5,"t":"The light shines in the darkness, and the darkness hasn’t overcome it."},{"v":6,"t":"There came a man sent from God, whose name was John."},{"v":7,"t":"The same came as a witness, that he might testify about the light, that all might believe through him."},{"v":8,"t":"He was not the light, but was sent that he might testify about the light."},{"v":9,"t":"The true light that enlightens everyone was coming into the world."},{"v":10,"t":"He was in the world, and the world was made through him, and the world didn’t recognize him."},{"v":11,"t":"He came to his own, and those who were his own didn’t receive him."},{"v":12,"t":"But as many as received him, to them he gave the right to become God’s children, to those who believe in his name:"},{"v":13,"t":"who were born, not of blood, nor of the will of the flesh, nor of the will of man, but of God."},{"v":14,"t":"The Word became flesh and lived among us. We saw his glory, such glory as of the only born Son of the Father, full of grace and truth."},{"v":15,"t":"John testified about him. He cried out, saying, “This was he of whom I said, ‘He who comes after me has surpassed me, for he was before me.’”"},{"v":16,"t":"From his fullness we all received grace upon grace."},{"v":17,"t":"For the law was given through Moses. Grace and truth were realized through Jesus Christ."},{"v":18,"t":"No one has seen God at any time. The only born Son, who is in the bosom of the Father, has declared him."},{"v":19,"t":"This is John’s testimony, when the Jews sent priests and Levites from Jerusalem to ask him, “Who are you?”"},{"v":20,"t":"He declared, and didn’t deny, but he declared, “I am not the Christ.”"},{"v":21,"t":"They asked him, “What then? Are you Elijah?” He said, “I am not.” “Are you the prophet?” He answered, “No.”"},{"v":22,"t":"They said therefore to him, “Who are you? Give us an answer to take back to those who sent us. What do you say about yourself?”"},{"v":23,"t":"He said, “I am the voice of one crying in the wilderness, ‘Make straight the way of the Lord,’ as Isaiah the prophet said.”"},{"v":24,"t":"The ones who had been sent were from the Pharisees."},{"v":25,"t":"They asked him, “Why then do you baptize if you are not the Christ, nor Elijah, nor the prophet?”"},{"v":26,"t":"John answered them, “I baptize in water, but among you stands one whom you don’t know."},{"v":27,"t":"He is the one who comes after me, who is preferred before me, whose sandal strap I’m not worthy to loosen.”"},{"v":28,"t":"These things were done in Bethany beyond the Jordan, where John was baptizing."},{"v":29,"t":"The next day, he saw Jesus coming to him, and said, “Behold, the Lamb of God, who takes away the sin of the world!"},{"v":30,"t":"This is he of whom I said, ‘After me comes a man who is preferred before me, for he was before me.’"},{"v":31,"t":"I didn’t know him, but for this reason I came baptizing in water, that he would be revealed to Israel.”"},{"v":32,"t":"John testified, saying, “I have seen the Spirit descending like a dove out of heaven, and it remained on him."},{"v":33,"t":"I didn’t recognize him, but he who sent me to baptize in water said to me, ‘On whomever you will see the Spirit descending and remaining on him is he who baptizes in the Holy Spirit.’"},{"v":34,"t":"I have seen and have testified that this is the Son of God.”"},{"v":35,"t":"Again, the next day, John was standing with two of his disciples,"},{"v":36,"t":"and he looked at Jesus as he walked, and said, “Behold, the Lamb of God!”"},{"v":37,"t":"The two disciples heard him speak, and they followed Jesus."},{"v":38,"t":"Jesus turned and saw them following, and said to them, “What are you looking for?” They said to him, “Rabbi” (which is to say, being interpreted, Teacher), “where are you staying?”"},{"v":39,"t":"He said to them, “Come and see.” They came and saw where he was staying, and they stayed with him that day. It was about the tenth hour."},{"v":40,"t":"One of the two who heard John and followed him was Andrew, Simon Peter’s brother."},{"v":41,"t":"He first found his own brother, Simon, and said to him, “We have found the Messiah!” (which is, being interpreted, Christ)."},{"v":42,"t":"He brought him to Jesus. Jesus looked at him and said, “You are Simon the son of Jonah. You shall be called Cephas” (which is by interpretation, Peter)."},{"v":43,"t":"On the next day, he was determined to go out into Galilee, and he found Philip. Jesus said to him, “Follow me.”"},{"v":44,"t":"Now Philip was from Bethsaida, the city of Andrew and Peter."},{"v":45,"t":"Philip found Nathanael, and said to him, “We have found him of whom Moses in the law and also the prophets, wrote: Jesus of Nazareth, the son of Joseph.”"},{"v":46,"t":"Nathanael said to him, “Can any good thing come out of Nazareth?” Philip said to him, “Come and see.”"},{"v":47,"t":"Jesus saw Nathanael coming to him, and said about him, “Behold, an Israelite indeed, in whom is no deceit!”"},{"v":48,"t":"Nathanael said to him, “How do you know me?” Jesus answered him, “Before Philip called you, when you were under the fig tree, I saw you.”"},{"v":49,"t":"Nathanael answered him, “Rabbi, you are the Son of God! You are King of Israel!”"},{"v":50,"t":"Jesus answered him, “Because I told you, ‘I saw you underneath the fig tree,’ do you believe? You will see greater things than these!”"},{"v":51,"t":"He said to him, “Most certainly, I tell you all, hereafter you will see heaven opened, and the angels of God ascending and descending on the Son of Man.”"}],"hr":[{"v":1,"t":"U početku bijaše Riječ i Riječ bijaše u Boga i Riječ bijaše Bog."},{"v":2,"t":"Ona bijaše u početku u Boga."},{"v":3,"t":"Sve postade po njoj i bez nje ne postade ništa. Svemu što postade"},{"v":4,"t":"u njoj bijaše život i život bijaše ljudima svjetlo;"},{"v":5,"t":"i svjetlo u tami svijetli i tama ga ne obuze."},{"v":6,"t":"Bi čovjek poslan od Boga, ime mu Ivan."},{"v":7,"t":"On dođe kao svjedok da posvjedoči za Svjetlo da svi vjeruju po njemu."},{"v":8,"t":"Ne bijaše on Svjetlo, nego - da posvjedoči za Svjetlo."},{"v":9,"t":"Svjetlo istinsko koje prosvjetljuje svakog čovjeka dođe na svijet;"},{"v":10,"t":"bijaše na svijetu i svijet po njemu posta i svijet ga ne upozna."},{"v":11,"t":"K svojima dođe i njegovi ga ne primiše."},{"v":12,"t":"A onima koji ga primiše podade moć da postanu djeca Božja: onima koji vjeruju u njegovo ime,"},{"v":13,"t":"koji su rođeni ne od krvi, ni od volje tjelesne, ni od volje muževlje, nego - od Boga."},{"v":14,"t":"I Riječ tijelom postade i nastani se među nama i vidjesmo slavu njegovu - slavu koju ima kao Jedinorođenac od Oca - pun milosti i istine."},{"v":15,"t":"Ivan svjedoči za njega. Viče: “To je onaj o kojem rekoh: koji za mnom dolazi, preda mnom je jer bijaše prije mene!”"},{"v":16,"t":"Doista, od punine njegove svi mi primismo, i to milost na milost."},{"v":17,"t":"Uistinu, Zakon bijaše dan po Mojsiju, a milost i istina nasta po Isusu Kristu."},{"v":18,"t":"Boga nitko nikada ne vidje: Jedinorođenac - Bog - koji je u krilu Očevu, on ga obznani."},{"v":19,"t":"A evo svjedočanstva Ivanova. Kad su Židovi iz Jeruzalema poslali k njemu svećenike i levite da ga upitaju: “Tko si ti?”,"},{"v":20,"t":"on prizna; ne zanijeka, nego prizna: “Ja nisam Krist.”"},{"v":21,"t":"Upitaše ga nato: “Što dakle? Jesi li Ilija?” Odgovori: “Nisam.” “Jesi li Prorok?” Odgovori: “Ne.”"},{"v":22,"t":"Tada mu rekoše: “Pa tko si da dadnemo odgovor onima koji su nas poslali? Što kažeš sam o sebi?”"},{"v":23,"t":"On odgovori: “Ja sam glas koji viče u pustinji: Poravnite put Gospodnji! - kako reče prorok Izaija.”"},{"v":24,"t":"A neki izaslanici bijahu farizeji."},{"v":25,"t":"Oni prihvatiše riječ i upitaše ga: “Zašto onda krstiš kad nisi Krist, ni Ilija, ni Prorok?”"},{"v":26,"t":"Ivan im odgovori: “Ja krstim vodom. Među vama stoji koga vi ne poznate -"},{"v":27,"t":"onaj koji za mnom dolazi, komu ja nisam dostojan odriješiti remenje na obući.”"},{"v":28,"t":"To se dogodilo u Betaniji s onu stranu Jordana, gdje je Ivan krstio."},{"v":29,"t":"Sutradan Ivan ugleda Isusa gdje dolazi k njemu pa reče: “Evo Jaganjca Božjega koji odnosi grijeh svijeta!”"},{"v":30,"t":"To je onaj o kojem rekoh: Za mnom dolazi čovjek koji je preda mnom jer bijaše prije mene!”"},{"v":31,"t":"“Ja ga nisam poznavao, ali baš zato dođoh i krstim vodom da se on očituje Izraelu.”"},{"v":32,"t":"I posvjedoči Ivan: “Promatrao sam Duha gdje s neba silazi kao golub i ostaje na njemu."},{"v":33,"t":"Njega ja nisam poznavao, ali onaj koji me posla vodom krstiti reče mi: 'Na koga vidiš da Duh silazi i ostaje na njemu, to je onaj koji krsti Duhom Svetim.'"},{"v":34,"t":"I ja sam to vidio i svjedočim: on je Sin Božji.”"},{"v":35,"t":"Sutradan opet stajaše Ivan s dvojicom svojih učenika."},{"v":36,"t":"Ugleda Isusa koji je onuda prolazio i reče: “Evo Jaganjca Božjega!”"},{"v":37,"t":"Te njegove riječi čula ona dva njegova učenika pa pođoše za Isusom."},{"v":38,"t":"Isus se obazre i vidjevši da idu za njim, upita ih: “Što tražite?” Oni mu rekoše: “Rabbi” - što znači: “Učitelju - gdje stanuješ?”"},{"v":39,"t":"Reče im: “Dođite i vidjet ćete.” Pođoše dakle i vidješe gdje stanuje i ostadoše kod njega onaj dan. Bila je otprilike deseta ura."},{"v":40,"t":"Jedan od one dvojice, koji su čuvši Ivana pošli za Isusom, bijaše Andrija, brat Šimuna Petra."},{"v":41,"t":"On najprije nađe svoga brata Šimuna te će mu: “Našli smo Mesiju!” - što znači “Krist - Pomazanik”."},{"v":42,"t":"Dovede ga Isusu, a Isus ga pogleda i reče: “Ti si Šimun, sin Ivanov! Zvat ćeš se Kefa!” - što znači “Petar - Stijena”."},{"v":43,"t":"Sutradan naumi Isus poći u Galileju. Nađe Filipa i reče mu: “Pođi za mnom!”"},{"v":44,"t":"Filip je bio iz Betsaide, iz grada Andrijina i Petrova."},{"v":45,"t":"Filip nađe Natanaela i javi mu: “Našli smo onoga o kome je pisao Mojsije u Zakonu i Proroci: Isusa, sina Josipova, iz Nazareta.”"},{"v":46,"t":"Reče mu Natanael: “Iz Nazareta da može biti što dobro?” Kaže mu Filip: “Dođi i vidi.”"},{"v":47,"t":"Kad Isus ugleda gdje Natanael dolazi k njemu, reče za njega: “Evo istinitog Izraelca u kojem nema prijevare!”"},{"v":48,"t":"Kaže mu Natanael: “Odakle me poznaješ?” Odgovori mu Isus: “Vidjeh te prije negoli te Filip pozva, dok si bio pod smokvom.”"},{"v":49,"t":"Nato će mu Natanael: “Učitelju, ti si Sin Božji! Ti kralj si Izraelov!”"},{"v":50,"t":"Odgovori mu Isus: “Stoga što ti rekoh: 'Vidjeh te pod smokvom', vjeruješ. I više ćeš od toga vidjeti!”"},{"v":51,"t":"I nadoda: “Zaista, zaista, kažem vam: gledat ćete otvoreno nebo i anđele Božje gdje uzlaze i silaze nad Sina Čovječjega.”"}]},"2":{"fa":[{"v":1,"t":"و در روز سوم، در قانای جلیل عروسی بودو مادر عیسی در آنجا بود."},{"v":2,"t":"و عیسی وشاگردانش را نیز به عروسی دعوت کردند."},{"v":3,"t":"وچون شراب تمام شد، مادر عیسی بدو گفت: «شراب ندارند.»"},{"v":4,"t":"عیسی به وی گفت: «ای زن مرابا تو چه‌کار است؟ ساعت من هنوز نرسیده است.»"},{"v":5,"t":"مادرش به نوکران گفت: «هر‌چه به شماگوید بکنید.»"},{"v":6,"t":"و در آنجا شش قدح سنگی برحسب تطهیریهود نهاده بودند که هر یک گنجایش دو یا سه کیل داشت."},{"v":7,"t":"عیسی بدیشان گفت: «قدحها را ازآب پر کنید.» و آنها را لبریز کردند."},{"v":8,"t":"پس بدیشان گفت: «الان بردارید و به نزد رئیس مجلس ببرید.» پس بردند؛"},{"v":9,"t":"و چون رئیس مجلس آن آب را که شراب گردیده بود، بچشید و ندانست که از کجااست، لیکن نوکرانی که آب را کشیده بودند، می‌دانستند، رئیس مجلس داماد را مخاطب ساخته، بدو گفت:"},{"v":10,"t":"«هرکسی شراب خوب رااول می‌آورد و چون مست شدند، بدتر از آن. لیکن تو شراب خوب را تا حال نگاه داشتی؟»"},{"v":11,"t":"و این ابتدای معجزاتی است که از عیسی درقانای جلیل صادر گشت و جلال خود را ظاهرکرد و شاگردانش به او ایمان آوردند."},{"v":12,"t":"و بعد ازآن او با مادر و برادران و شاگردان خود به کفرناحوم آمد و در آنجا ایامی کم ماندند."},{"v":13,"t":"و چون عید فصح نزدیک بود، عیسی به اورشلیم رفت،"},{"v":14,"t":"و در هیکل، فروشندگان گاو وگوسفند و کبوتر و صرافان را نشسته یافت."},{"v":15,"t":"پس تازیانه‌ای از ریسمان ساخته، همه را از هیکل بیرون نمود، هم گوسفندان و گاوان را، و نقودصرافان را ریخت و تختهای ایشان را واژگون ساخت،"},{"v":16,"t":"و به کبوترفروشان گفت: «اینها را ازاینجا بیرون برید و خانه پدر مرا خانه تجارت مسازید.»"},{"v":17,"t":"آنگاه شاگردان او را یاد آمد که مکتوب است: «غیرت خانه تو مرا خورده است.»"},{"v":18,"t":"پس یهودیان روی به او آورده، گفتند: «به ما چه علامت می‌نمایی که این کارها را می‌کنی؟»"},{"v":19,"t":"عیسی در جواب ایشان گفت: «این قدس راخراب کنید که در سه روز آن را برپا خواهم نمود.»"},{"v":20,"t":"آنگاه یهودیان گفتند: «در عرصه چهل و شش سال این قدس را بنا نموده‌اند؛ آیا تو درسه روز آن را برپا می‌کنی؟»"},{"v":21,"t":"لیکن او درباره قدس جسد خود سخن می‌گفت."},{"v":22,"t":"پس وقتی که از مردگان برخاست شاگردانش را به‌خاطر آمد که این را بدیشان گفته بود. آنگاه به کتاب و به کلامی که عیسی گفته بود، ایمان آوردند."},{"v":23,"t":"و هنگامی که در عید فصح در اورشلیم بودبسیاری چون معجزاتی را که از او صادر می‌گشت دیدند، به اسم او ایمان آوردند."},{"v":24,"t":"لیکن عیسی خویشتن را بدیشان موتمن نساخت، زیرا که اوهمه را می‌شناخت."},{"v":25,"t":"و از آنجا که احتیاج نداشت که کسی درباره انسان شهادت دهد، زیراخود آنچه در انسان بود می‌دانست."}],"en":[{"v":1,"t":"The third day, there was a wedding in Cana of Galilee. Jesus’ mother was there."},{"v":2,"t":"Jesus also was invited, with his disciples, to the wedding."},{"v":3,"t":"When the wine ran out, Jesus’ mother said to him, “They have no wine.”"},{"v":4,"t":"Jesus said to her, “Woman, what does that have to do with you and me? My hour has not yet come.”"},{"v":5,"t":"His mother said to the servants, “Whatever he says to you, do it.”"},{"v":6,"t":"Now there were six water pots of stone set there after the Jews’ way of purifying, containing two or three metretes apiece."},{"v":7,"t":"Jesus said to them, “Fill the water pots with water.” So they filled them up to the brim."},{"v":8,"t":"He said to them, “Now draw some out, and take it to the ruler of the feast.” So they took it."},{"v":9,"t":"When the ruler of the feast tasted the water now become wine, and didn’t know where it came from (but the servants who had drawn the water knew), the ruler of the feast called the bridegroom"},{"v":10,"t":"and said to him, “Everyone serves the good wine first, and when the guests have drunk freely, then that which is worse. You have kept the good wine until now!”"},{"v":11,"t":"This beginning of his signs Jesus did in Cana of Galilee, and revealed his glory; and his disciples believed in him."},{"v":12,"t":"After this, he went down to Capernaum, he, and his mother, his brothers, and his disciples; and they stayed there a few days."},{"v":13,"t":"The Passover of the Jews was at hand, and Jesus went up to Jerusalem."},{"v":14,"t":"He found in the temple those who sold oxen, sheep, and doves, and the changers of money sitting."},{"v":15,"t":"He made a whip of cords and drove all out of the temple, both the sheep and the oxen; and he poured out the changers’ money and overthrew their tables."},{"v":16,"t":"To those who sold the doves, he said, “Take these things out of here! Don’t make my Father’s house a marketplace!”"},{"v":17,"t":"His disciples remembered that it was written, “Zeal for your house will eat me up.”"},{"v":18,"t":"The Jews therefore answered him, “What sign do you show us, seeing that you do these things?”"},{"v":19,"t":"Jesus answered them, “Destroy this temple, and in three days I will raise it up.”"},{"v":20,"t":"The Jews therefore said, “It took forty-six years to build this temple! Will you raise it up in three days?”"},{"v":21,"t":"But he spoke of the temple of his body."},{"v":22,"t":"When therefore he was raised from the dead, his disciples remembered that he said this, and they believed the Scripture and the word which Jesus had said."},{"v":23,"t":"Now when he was in Jerusalem at the Passover, during the feast, many believed in his name, observing his signs which he did."},{"v":24,"t":"But Jesus didn’t entrust himself to them, because he knew everyone,"},{"v":25,"t":"and because he didn’t need for anyone to testify concerning man; for he himself knew what was in man."}],"hr":[{"v":1,"t":"Trećeg dana bijaše svadba u Kani Galilejskoj. Bila ondje Isusova majka."},{"v":2,"t":"Na svadbu bijaše pozvan i Isus i njegovi učenici."},{"v":3,"t":"Kad ponesta vina, Isusu će njegova majka: “Vina nemaju.”"},{"v":4,"t":"Kaže joj Isus: “Ženo, što ja imam s tobom? Još nije došao moj čas!”"},{"v":5,"t":"Nato će njegova mati poslužiteljima: “Što god vam rekne, učinite!”"},{"v":6,"t":"A bijaše ondje Židovima za čišćenje šest kamenih posuda od po dvije do tri mjere."},{"v":7,"t":"Kaže Isus poslužiteljima: “Napunite posude vodom!” I napune ih do vrha."},{"v":8,"t":"Tada im reče: “Zagrabite sada i nosite ravnatelju stola.” Oni odnesu."},{"v":9,"t":"Kad okusi vodu što posta vinom, a nije znao odakle je - znale su sluge koje zagrabiše vodu - ravnatelj stola pozove zaručnika"},{"v":10,"t":"i kaže mu: “Svaki čovjek stavlja na stol najprije dobro vino, a kad se ponapiju, gore. Ti si čuvao dobro vino sve do sada.”"},{"v":11,"t":"Tako, u Kani Galilejskoj, učini Isus prvo znamenje i objavi svoju slavu te povjerovaše u njega njegovi učenici."},{"v":12,"t":"Nakon toga siđe sa svojom majkom, s braćom i sa svojim učenicima u Kafarnaum. Ondje ostadoše nekoliko dana."},{"v":13,"t":"Blizu bijaše židovska Pasha. Stoga Isus uziđe u Jeruzalem."},{"v":14,"t":"U Hramu nađe prodavače volova, ovaca i golubova i mjenjače gdje sjede."},{"v":15,"t":"I načini bič od užeta te ih sve istjera iz Hrama zajedno s ovcama i volovima. Mjenjačima rasu novac i stolove isprevrta,"},{"v":16,"t":"a prodavačima golubova reče: “Nosite to odavde i ne činite od kuće Oca mojega kuću trgovačku.”"},{"v":17,"t":"Prisjetiše se njegovi učenici da je pisano: Izjeda me revnost za Dom tvoj."},{"v":18,"t":"Nato se umiješaju Židovi i upitaju ga: “Koje nam znamenje možeš pokazati da to smiješ činiti?”"},{"v":19,"t":"Odgovori im Isus: “Razvalite ovaj hram i ja ću ga u tri dana podići.”"},{"v":20,"t":"Rekoše mu nato Židovi: “Četrdeset i šest godina gradio se ovaj Hram, a ti da ćeš ga u tri dana podići?”"},{"v":21,"t":"No on je govorio o hramu svoga tijela."},{"v":22,"t":"Pošto uskrsnu od mrtvih, prisjetiše se njegovi učenici da je to htio reći te povjerovaše Pismu i besjedi koju Isus reče."},{"v":23,"t":"Dok je boravio u Jeruzalemu o blagdanu Pashe, mnogi povjerovaše u njegovo ime promatrajući znamenja koja je činio."},{"v":24,"t":"No sam se Isus njima nije povjeravao jer ih je sve dobro poznavao"},{"v":25,"t":"i nije trebalo da mu tko daje svjedočanstvo o čovjeku: ta sam je dobro znao što je u čovjeku."}]},"3":{"fa":[{"v":1,"t":"و شخصی از فریسیان نیقودیموس نام ازروسای یهود بود."},{"v":2,"t":"او در شب نزد عیسی آمده، به وی گفت: «ای استاد می‌دانیم که تو معلم هستی که از جانب خدا آمده‌ای زیرا هیچ‌کس نمی تواند معجزاتی را که تو می‌نمایی بنماید، جزاینکه خدا با وی باشد.»"},{"v":3,"t":"عیسی در جواب اوگفت: «آمین آمین به تو می‌گویم اگر کسی از سر نومولود نشود، ملکوت خدا را نمی تواند دید.»"},{"v":4,"t":"نیقودیموس بدو گفت: «چگونه ممکن است که انسانی که پیر شده باشد، مولود گردد؟ آیا می‌شودکه بار دیگر داخل شکم مادر گشته، مولود شود؟»"},{"v":5,"t":"عیسی در جواب گفت: «آمین، آمین به تومی گویم اگر کسی از آب و روح مولود نگردد، ممکن نیست که داخل ملکوت خدا شود."},{"v":6,"t":"آنچه از جسم مولود شد، جسم است و آنچه از روح مولود گشت روح است."},{"v":7,"t":"عجب مدار که به توگفتم باید شما از سر نو مولود گردید."},{"v":8,"t":"باد هرجاکه می‌خواهد می‌وزد و صدای آن را می‌شنوی لیکن نمی دانی از کجا می‌آید و به کجا می‌رود. همچنین است هر‌که از روح مولود گردد.»"},{"v":9,"t":"نیقودیموس در جواب وی گفت: «چگونه ممکن است که چنین شود؟»"},{"v":10,"t":"عیسی در جواب وی گفت: «آیا تو معلم اسرائیل هستی و این رانمی دانی؟"},{"v":11,"t":"آمین، آمین به تو می‌گویم آنچه می‌دانیم، می‌گوییم و به آنچه دیده‌ایم، شهادت می‌دهیم و شهادت ما را قبول نمی کنید."},{"v":12,"t":"چون شما را از امور زمینی سخن گفتم، باور نکردید. پس هرگاه به امور آسمانی با شما سخن رانم چگونه تصدیق خواهید نمود؟"},{"v":13,"t":"و کسی به آسمان بالا نرفت مگر آن کس که از آسمان پایین آمد یعنی پسر انسان که در آسمان است."},{"v":14,"t":"وهمچنان‌که موسی مار را در بیابان بلند نمود، همچنین پسر انسان نیز باید بلند کرده شود،"},{"v":15,"t":"تاهر‌که به او ایمان آرد هلاک نگردد، بلکه حیات جاودانی یابد."},{"v":16,"t":"زیرا خدا جهان را اینقدر محبت نمود که پسر یگانه خود را داد تا هر‌که بر او ایمان آورد هلاک نگردد بلکه حیات جاودانی یابد."},{"v":17,"t":"زیرا خدا پسر خود را در جهان نفرستاد تا برجهان داوری کند، بلکه تا به وسیله او جهان نجات یابد."},{"v":18,"t":"آنکه به او ایمان آرد، بر او حکم نشود؛ اما هر‌که ایمان نیاورد الان بر او حکم شده است، بجهت آنکه به اسم پسر یگانه خدا ایمان نیاورده."},{"v":19,"t":"و حکم این است که نور در جهان آمدو مردم ظلمت را بیشتر از نور دوست داشتند، ازآنجا که اعمال ایشان بد است."},{"v":20,"t":"زیرا هر‌که عمل بد می‌کند، روشنی را دشمن دارد و پیش روشنی نمی آید، مبادا اعمال او توبیخ شود."},{"v":21,"t":"و لیکن کسی‌که به راستی عمل می‌کند پیش روشنی می‌آید تا آنکه اعمال او هویدا گردد که در خداکرده شده است.»"},{"v":22,"t":"و بعد از آن عیسی با شاگردان خود به زمین یهودیه آمد و با ایشان در آنجا به‌سر برده، تعمیدمی داد."},{"v":23,"t":"و یحیی نیز در عینون، نزدیک سالیم تعمید می‌داد زیرا که در آنجا آب بسیار بود ومردم می‌آمدند و تعمید می‌گرفتند،"},{"v":24,"t":"چونکه یحیی هنوز در زندان حبس نشده بود."},{"v":25,"t":"آنگاه در خصوص تطهیر، در میان شاگردان یحیی ویهودیان مباحثه شد."},{"v":26,"t":"پس به نزد یحیی آمده، به او گفتند: «ای استاد، آن شخصی که با تو درآنطرف اردن بود و تو برای او شهادت دادی، اکنون او تعمید می‌دهد و همه نزد اومی آیند.»"},{"v":27,"t":"یحیی در جواب گفت: «هیچ‌کس چیزی نمی تواند یافت، مگر آنکه از آسمان بدو داده شود."},{"v":28,"t":"شما خود بر من شاهد هستید که گفتم من مسیح نیستم بلکه پیش روی او فرستاده شدم."},{"v":29,"t":"کسی‌که عروس دارد داماد است، اما دوست داماد که ایستاده آواز او را می‌شنود، از آواز دامادبسیار خشنود می‌گردد. پس این خوشی من کامل گردید."},{"v":30,"t":"می‌باید که او افزوده شود و من ناقص گردم."},{"v":31,"t":"او که از بالا می‌آید، بالای همه است وآنکه از زمین است زمینی است و از زمین تکلم می‌کند؛ اما او که از آسمان می‌آید، بالای همه است."},{"v":32,"t":"و آنچه را دید و شنید، به آن شهادت می‌دهد و هیچ‌کس شهادت او را قبول نمی کند."},{"v":33,"t":"و کسی‌که شهادت اورا قبول کرد، مهر کرده است بر اینکه خدا راست است."},{"v":34,"t":"زیرا آن کسی را که خدا فرستاد، به کلام خدا تکلم می‌نماید، چونکه خدا روح را به میزان عطا نمی کند."},{"v":35,"t":"پدرپسر را محبت می‌نماید و همه‌چیز را بدست اوسپرده است."},{"v":36,"t":"آنکه به پسر ایمان آورده باشد، حیات جاودانی دارد و آنکه به پسر ایمان نیاوردحیات را نخواهد دید، بلکه غضب خدا بر اومی ماند.»"}],"en":[{"v":1,"t":"Now there was a man of the Pharisees named Nicodemus, a ruler of the Jews."},{"v":2,"t":"He came to Jesus by night and said to him, “Rabbi, we know that you are a teacher come from God, for no one can do these signs that you do, unless God is with him.”"},{"v":3,"t":"Jesus answered him, “Most certainly I tell you, unless one is born anew, he can’t see God’s Kingdom.”"},{"v":4,"t":"Nicodemus said to him, “How can a man be born when he is old? Can he enter a second time into his mother’s womb and be born?”"},{"v":5,"t":"Jesus answered, “Most certainly I tell you, unless one is born of water and Spirit, he can’t enter into God’s Kingdom."},{"v":6,"t":"That which is born of the flesh is flesh. That which is born of the Spirit is spirit."},{"v":7,"t":"Don’t marvel that I said to you, ‘You must be born anew.’"},{"v":8,"t":"The wind blows where it wants to, and you hear its sound, but don’t know where it comes from and where it is going. So is everyone who is born of the Spirit.”"},{"v":9,"t":"Nicodemus answered him, “How can these things be?”"},{"v":10,"t":"Jesus answered him, “Are you the teacher of Israel, and don’t understand these things?"},{"v":11,"t":"Most certainly I tell you, we speak that which we know and testify of that which we have seen, and you don’t receive our witness."},{"v":12,"t":"If I told you earthly things and you don’t believe, how will you believe if I tell you heavenly things?"},{"v":13,"t":"No one has ascended into heaven but he who descended out of heaven, the Son of Man, who is in heaven."},{"v":14,"t":"As Moses lifted up the serpent in the wilderness, even so must the Son of Man be lifted up,"},{"v":15,"t":"that whoever believes in him should not perish, but have eternal life."},{"v":16,"t":"For God so loved the world, that he gave his only born Son, that whoever believes in him should not perish, but have eternal life."},{"v":17,"t":"For God didn’t send his Son into the world to judge the world, but that the world should be saved through him."},{"v":18,"t":"He who believes in him is not judged. He who doesn’t believe has been judged already, because he has not believed in the name of the only born Son of God."},{"v":19,"t":"This is the judgment, that the light has come into the world, and men loved the darkness rather than the light, for their works were evil."},{"v":20,"t":"For everyone who does evil hates the light and doesn’t come to the light, lest his works would be exposed."},{"v":21,"t":"But he who does the truth comes to the light, that his works may be revealed, that they have been done in God.”"},{"v":22,"t":"After these things, Jesus came with his disciples into the land of Judea. He stayed there with them and baptized."},{"v":23,"t":"John also was baptizing in Enon near Salim, because there was much water there. They came and were baptized;"},{"v":24,"t":"for John was not yet thrown into prison."},{"v":25,"t":"Therefore a dispute arose on the part of John’s disciples with some Jews about purification."},{"v":26,"t":"They came to John and said to him, “Rabbi, he who was with you beyond the Jordan, to whom you have testified, behold, he baptizes, and everyone is coming to him.”"},{"v":27,"t":"John answered, “A man can receive nothing unless it has been given him from heaven."},{"v":28,"t":"You yourselves testify that I said, ‘I am not the Christ,’ but, ‘I have been sent before him.’"},{"v":29,"t":"He who has the bride is the bridegroom; but the friend of the bridegroom, who stands and hears him, rejoices greatly because of the bridegroom’s voice. Therefore my joy is made full."},{"v":30,"t":"He must increase, but I must decrease."},{"v":31,"t":"“He who comes from above is above all. He who is from the earth belongs to the earth and speaks of the earth. He who comes from heaven is above all."},{"v":32,"t":"What he has seen and heard, of that he testifies; and no one receives his witness."},{"v":33,"t":"He who has received his witness has set his seal to this, that God is true."},{"v":34,"t":"For he whom God has sent speaks the words of God; for God gives the Spirit without measure."},{"v":35,"t":"The Father loves the Son, and has given all things into his hand."},{"v":36,"t":"One who believes in the Son has eternal life, but one who disobeys the Son won’t see life, but the wrath of God remains on him.”"}],"hr":[{"v":1,"t":"Bijaše među farizejima čovjek imenom Nikodem, ugledan Židov."},{"v":2,"t":"On dođe Isusu obnoć i reče mu: “Rabbi, znamo da si od Boga došao kao učitelj jer nitko ne može činiti znamenja kakva ti činiš ako Bog nije s njime.”"},{"v":3,"t":"Odgovori mu Isus: “Zaista, zaista, kažem ti: tko se ne rodi nanovo, odozgor, ne može vidjeti kraljevstva Božjega!”"},{"v":4,"t":"Kaže mu Nikodem: “Kako se čovjek može roditi kad je star? Zar može po drugi put ući u utrobu majke svoje i roditi se?”"},{"v":5,"t":"Odgovori Isus: “Zaista, zaista, kažem ti: ako se tko ne rodi iz vode i Duha, ne može ući u kraljevstvo Božje."},{"v":6,"t":"Što je od tijela rođeno, tijelo je; i što je od Duha rođeno, duh je."},{"v":7,"t":"Ne čudi se što ti rekoh: 'Treba da se rodite nanovo, odozgor.'"},{"v":8,"t":"Vjetar puše gdje hoće; čuješ mu šum, a ne znaš odakle dolazi i kamo ide. Tako je sa svakim koji je rođen od Duha.”"},{"v":9,"t":"Upita ga Nikodem: “Kako se to može zbiti?”"},{"v":10,"t":"Odgovori mu Isus: “Ti si učitelj u Izraelu pa to da ne razumiješ?"},{"v":11,"t":"Zaista, zaista, kažem ti: govorimo što znamo, svjedočimo za ono što vidjesmo, ali svjedočanstva našega ne primate."},{"v":12,"t":"Ako vam rekoh zemaljsko pa ne vjerujete, kako ćete vjerovati kad vam budem govorio nebesko?"},{"v":13,"t":"Nitko nije uzašao na nebo doli onaj koji siđe s neba, Sin Čovječji."},{"v":14,"t":"I kao što je Mojsije podigao zmiju u pustinji tako ima biti podignut Sin Čovječji"},{"v":15,"t":"da svaki koji vjeruje u njemu ima život vječni."},{"v":16,"t":"Uistinu, Bog je tako ljubio svijet te je dao svoga Sina Jedinorođenca da nijedan koji u njega vjeruje ne propadne, nego da ima život vječni."},{"v":17,"t":"Ta Bog nije poslao Sina na svijet da sudi svijetu, nego da se svijet spasi po njemu."},{"v":18,"t":"Tko vjeruje u njega, ne osuđuje se; a tko ne vjeruje, već je osuđen što nije vjerovao u ime jedinorođenoga Sina Božjega."},{"v":19,"t":"A ovo je taj sud: Svjetlost je došla na svijet, ali ljudi su više ljubili tamu nego svjetlost jer djela im bijahu zla."},{"v":20,"t":"Uistinu, tko god čini zlo, mrzi svjetlost i ne dolazi k svjetlosti da se ne razotkriju djela njegova;"},{"v":21,"t":"a tko čini istinu, dolazi k svjetlosti nek bude bjelodano da su djela njegova u Bogu učinjena.”"},{"v":22,"t":"Poslije toga ode Isus sa svojim učenicima u Judejsku zemlju. Tu je boravio s njima i krstio."},{"v":23,"t":"A krstio je i Ivan, u Enonu blizu Salima, jer ondje bijaše mnogo vode. Ljudi su dolazili i krstili se."},{"v":24,"t":"Jer Ivan još nije bio bačen u tamnicu."},{"v":25,"t":"Između Ivanovih učenika i nekog Židova nastade tako prepirka o čišćenju."},{"v":26,"t":"Dođoše Ivanu i rekoše mu: “Učitelju, onaj koji s tobom bijaše s onu stranu Jordana i za kojega si ti svjedočio - on eno krsti i svi hrle k njemu.”"},{"v":27,"t":"Ivan odgovori: “Nitko ne može sebi uzeti ništa ako mu nije dano s neba."},{"v":28,"t":"Vi ste mi sami svjedoci da sam rekao: 'Nisam ja Krist, nego poslan sam pred njim.'"},{"v":29,"t":"Tko ima zaručnicu, zaručnik je. A prijatelj zaručnikov, koji stoji uza nj i sluša ga, klikće od radosti na glas zaručnikov. Ta se moja radost upravo ispunila."},{"v":30,"t":"On treba da raste, a ja da se umanjujem."},{"v":31,"t":"Tko odozgor dolazi, on je iznad sviju; tko je sa zemlje, zemaljski je i zemaljski govori. Tko dolazi s neba, on je iznad sviju:"},{"v":32,"t":"što je vidio i čuo - za to svjedoči, a svjedočanstva njegova nitko ne prima."},{"v":33,"t":"Tko primi njegovo svjedočanstvo, potvrđuje da je Bog istinit."},{"v":34,"t":"Uistinu, onaj koga Bog posla Božje riječi govori jer Bog Duha ne daje na mjeru."},{"v":35,"t":"Otac ljubi Sina i sve je predao u ruku njegovu."},{"v":36,"t":"Tko vjeruje u Sina, ima vječni život; a tko neće da vjeruje u Sina, neće vidjeti života; gnjev Božji ostaje na njemu.”"}]},"4":{"fa":[{"v":1,"t":"و چون خداوند دانست که فریسیان مطلع شده‌اند که عیسی بیشتر از یحیی شاگردپیدا کرده، تعمید می‌دهد،"},{"v":2,"t":"با اینکه خود عیسی تعمید نمی داد بلکه شاگردانش،"},{"v":3,"t":"یهودیه راگذارده، باز به‌جانب جلیل رفت."},{"v":4,"t":"و لازم بود که از سامره عبور کند"},{"v":5,"t":"پس به شهری از سامره که سوخار نام داشت، نزدیک به آن موضعی که یعقوب به پسر خود یوسف داده بود رسید."},{"v":6,"t":"و در آنجا چاه یعقوب بود. پس عیسی از سفر خسته شده، همچنین بر سر چاه نشسته بود و قریب به ساعت ششم بود."},{"v":7,"t":"که زنی سامری بجهت آب کشیدن آمد. عیسی بدو گفت: «جرعه‌ای آب به من بنوشان.»"},{"v":8,"t":"زیرا شاگردانش بجهت خریدن خوراک به شهر رفته بودند."},{"v":9,"t":"زن سامری بدو گفت: «چگونه تو که یهود هستی ازمن آب می‌خواهی و حال آنکه زن سامری می‌باشم؟» زیرا که یهود با سامریان معاشرت ندارند."},{"v":10,"t":"عیسی در جواب او گفت: «اگر بخشش خدا را می‌دانستی و کیست که به تو می‌گوید آب به من بده، هرآینه تو از او خواهش می‌کردی و به تو آب زنده عطا می‌کرد."},{"v":11,"t":"زن بدو گفت: «ای آقادلو نداری و چاه عمیق است. پس از کجا آب زنده داری؟"},{"v":12,"t":"آیا تو از پدر ما یعقوب بزرگترهستی که چاه را به ما داد و خود و پسران و مواشی او از آن می‌آشامیدند؟»"},{"v":13,"t":"عیسی در جواب اوگفت: «هر‌که از این آب بنوشد باز تشنه گردد،"},{"v":14,"t":"لیکن کسی‌که از آبی که من به او می‌دهم بنوشد، ابد تشنه نخواهد شد، بلکه آن آبی که به او می‌دهم در او چشمه آبی گردد که تا حیات جاودانی می‌جوشد.»"},{"v":15,"t":"زن بدو گفت: «ای آقا آن آب را به من بده تا دیگر تشنه نگردم و به اینجابجهت آب کشیدن نیایم.»"},{"v":16,"t":"عیسی به او گفت: «برو و شوهر خود رابخوان و در اینجا بیا.»"},{"v":17,"t":"زن در جواب گفت: «شوهر ندارم.» عیسی بدو گفت: «نیکو گفتی که شوهر نداری!"},{"v":18,"t":"زیرا که پنج شوهر داشتی وآنکه الان داری شوهر تو نیست! این سخن راراست گفتی!»"},{"v":19,"t":"زن بدو گفت: «ای آقا می‌بینم که تو نبی هستی!"},{"v":20,"t":"پدران ما در این کوه پرستش می‌کردند و شما می‌گویید که در اورشلیم جایی است که در آن عبادت باید نمود.»"},{"v":21,"t":"عیسی بدوگفت: «ای زن مرا تصدیق کن که ساعتی می‌آید که نه در این کوه و نه در اورشلیم پدر را پرستش خواهید کرد."},{"v":22,"t":"شما آنچه را که نمی دانیدمی پرستید اما ما آنچه را که می‌دانیم عبادت می‌کنیم زیرا نجات از یهود است."},{"v":23,"t":"لیکن ساعتی می‌آید بلکه الان است که در آن پرستندگان حقیقی پدر را به روح و راستی پرستش خواهندکرد زیرا که پدر مثل این پرستندگان خود را طالب است."},{"v":24,"t":"خدا روح است و هر‌که او را پرستش کند می‌باید به روح و راستی بپرستد.»"},{"v":25,"t":"زن بدو گفت: «می‌دانم که مسیح یعنی کرستس می‌آید. پس هنگامی که او آید از هر چیزبه ما خبر‌خواهد داد.»"},{"v":26,"t":"عیسی بدو گفت: «من که با تو سخن می‌گویم همانم.»"},{"v":27,"t":"و در همان وقت شاگردانش آمده، تعجب کردند که با زنی سخن می‌گوید و لکن هیچ‌کس نگفت که چه می‌طلبی یا برای چه با او حرف می‌زنی."},{"v":28,"t":"آنگاه زن سبوی خود را گذارده، به شهر رفت و مردم را گفت:"},{"v":29,"t":"«بیایید و کسی راببینید که هرآنچه کرده بودم به من گفت. آیا این مسیح نیست؟»"},{"v":30,"t":"پس از شهر بیرون شده، نزد اومی آمدند."},{"v":31,"t":"و در اثنا آن شاگردان او خواهش نموده، گفتند: «ای استاد بخور.»"},{"v":32,"t":"بدیشان گفت: «من غذایی دارم که بخورم و شما آن را نمی دانید.»"},{"v":33,"t":"شاگردان به یکدیگر گفتند: «مگر کسی برای اوخوراکی آورده باشد!»"},{"v":34,"t":"عیسی بدیشان گفت: «خوراک من آن است که خواهش فرستنده خودرا به عمل آورم و کار او را به انجام رسانم."},{"v":35,"t":"آیاشما نمی گویید که چهار ماه دیگر موسم درواست؟ اینک به شما می‌گویم چشمان خود را بالاافکنید و مزرعه‌ها را ببینید زیرا که الان بجهت درو سفید شده است."},{"v":36,"t":"و دروگر اجرت می‌گیردو ثمری بجهت حیات جاودانی جمع می‌کند تاکارنده و درو‌کننده هر دو با هم خشنود گردند."},{"v":37,"t":"زیرا این کلام در اینجا راست است که یکی می‌کارد و دیگری درو می‌کند."},{"v":38,"t":"من شما رافرستادم تا چیزی را که در آن رنج نبرده‌اید دروکنید. دیگران محنت کشیدند و شما در محنت ایشان داخل شده‌اید.»"},{"v":39,"t":"پس در آن شهر بسیاری از سامریان بواسطه سخن آن زن که شهادت داد که هر‌آنچه کرده بودم به من باز‌گفت بدو ایمان آوردند."},{"v":40,"t":"و چون سامریان نزد او آمدند، از او خواهش کردند که نزدایشان بماند و دو روز در آنجا بماند."},{"v":41,"t":"و بسیاری دیگر بواسطه کلام او ایمان آوردند."},{"v":42,"t":"و به زن گفتند که «بعد از این بواسطه سخن تو ایمان نمی آوریم زیرا خود شنیده و دانسته‌ایم که او درحقیقت مسیح و نجات‌دهنده عالم است.»"},{"v":43,"t":"اما بعد از دو روز از آنجا بیرون آمده، به سوی جلیل روانه شد."},{"v":44,"t":"زیرا خود عیسی شهادت داد که هیچ نبی را در وطن خود حرمت نیست."},{"v":45,"t":"پس چون به جلیل آمد، جلیلیان او راپذیرفتند زیرا هر‌چه در اورشلیم در عید کرده بود، دیدند، چونکه ایشان نیز در عید رفته بودند."},{"v":46,"t":"پس عیسی به قانای جلیل آنجایی که آب را شراب ساخته بود، بازآمد. و یکی از سرهنگان ملک بود که پسر او در کفرناحوم مریض بود."},{"v":47,"t":"وچون شنید که عیسی از یهودیه به جلیل آمده است، نزد او آمده، خواهش کرد که فرود بیاید وپسر او را شفا دهد، زیرا که مشرف به موت بود."},{"v":48,"t":"عیسی بدو گفت: «اگر آیات و معجزات نبینید، همانا ایمان نیاورید.»"},{"v":49,"t":"سرهنگ بدو گفت: «ای آقا قبل از آنکه پسرم بمیرد فرود بیا.»"},{"v":50,"t":"عیسی بدو گفت: «برو که پسرت زنده است.» آن شخص به سخنی که عیسی بدو گفت، ایمان آورده، روانه شد."},{"v":51,"t":"و در وقتی که او می‌رفت، غلامانش او راستقبال نموده، مژده دادند و گفتند که پسر توزنده است."},{"v":52,"t":"پس از ایشان پرسید که در چه ساعت عافیت یافت. گفتند: «دیروز، در ساعت هفتم تب از او زایل گشت.»"},{"v":53,"t":"آنگاه پدر فهمیدکه در همان ساعت عیسی گفته بود: «پسر تو زنده است.» پس او و تمام اهل خانه او ایمان آوردند."},{"v":54,"t":"و این نیز معجزه دوم بود که از عیسی در وقتی که از یهودیه به جلیل آمد، به ظهور رسید."}],"en":[{"v":1,"t":"Therefore when the Lord knew that the Pharisees had heard that Jesus was making and baptizing more disciples than John"},{"v":2,"t":"(although Jesus himself didn’t baptize, but his disciples),"},{"v":3,"t":"he left Judea and departed into Galilee."},{"v":4,"t":"He needed to pass through Samaria."},{"v":5,"t":"So he came to a city of Samaria called Sychar, near the parcel of ground that Jacob gave to his son Joseph."},{"v":6,"t":"Jacob’s well was there. Jesus therefore, being tired from his journey, sat down by the well. It was about the sixth hour."},{"v":7,"t":"A woman of Samaria came to draw water. Jesus said to her, “Give me a drink.”"},{"v":8,"t":"For his disciples had gone away into the city to buy food."},{"v":9,"t":"The Samaritan woman therefore said to him, “How is it that you, being a Jew, ask for a drink from me, a Samaritan woman?” (For Jews have no dealings with Samaritans.)"},{"v":10,"t":"Jesus answered her, “If you knew the gift of God, and who it is who says to you, ‘Give me a drink,’ you would have asked him, and he would have given you living water.”"},{"v":11,"t":"The woman said to him, “Sir, you have nothing to draw with, and the well is deep. So where do you get that living water?"},{"v":12,"t":"Are you greater than our father Jacob, who gave us the well and drank from it himself, as did his children and his livestock?”"},{"v":13,"t":"Jesus answered her, “Everyone who drinks of this water will thirst again,"},{"v":14,"t":"but whoever drinks of the water that I will give him will never thirst again; but the water that I will give him will become in him a well of water springing up to eternal life.”"},{"v":15,"t":"The woman said to him, “Sir, give me this water, so that I don’t get thirsty, neither come all the way here to draw.”"},{"v":16,"t":"Jesus said to her, “Go, call your husband, and come here.”"},{"v":17,"t":"The woman answered, “I have no husband.” Jesus said to her, “You said well, ‘I have no husband,’"},{"v":18,"t":"for you have had five husbands; and he whom you now have is not your husband. This you have said truly.”"},{"v":19,"t":"The woman said to him, “Sir, I perceive that you are a prophet."},{"v":20,"t":"Our fathers worshiped in this mountain, and you Jews say that in Jerusalem is the place where people ought to worship.”"},{"v":21,"t":"Jesus said to her, “Woman, believe me, the hour is coming when neither in this mountain nor in Jerusalem will you worship the Father."},{"v":22,"t":"You worship that which you don’t know. We worship that which we know; for salvation is from the Jews."},{"v":23,"t":"But the hour comes, and now is, when the true worshipers will worship the Father in spirit and truth, for the Father seeks such to be his worshipers."},{"v":24,"t":"God is spirit, and those who worship him must worship in spirit and truth.”"},{"v":25,"t":"The woman said to him, “I know that Messiah is coming, he who is called Christ. When he has come, he will declare to us all things.”"},{"v":26,"t":"Jesus said to her, “I am he, the one who speaks to you.”"},{"v":27,"t":"Just then, his disciples came. They marveled that he was speaking with a woman; yet no one said, “What are you looking for?” or, “Why do you speak with her?”"},{"v":28,"t":"So the woman left her water pot, went away into the city, and said to the people,"},{"v":29,"t":"“Come, see a man who told me everything that I have done. Can this be the Christ?”"},{"v":30,"t":"They went out of the city, and were coming to him."},{"v":31,"t":"In the meanwhile, the disciples urged him, saying, “Rabbi, eat.”"},{"v":32,"t":"But he said to them, “I have food to eat that you don’t know about.”"},{"v":33,"t":"The disciples therefore said to one another, “Has anyone brought him something to eat?”"},{"v":34,"t":"Jesus said to them, “My food is to do the will of him who sent me and to accomplish his work."},{"v":35,"t":"Don’t you say, ‘There are yet four months until the harvest’? Behold, I tell you, lift up your eyes and look at the fields, that they are white for harvest already."},{"v":36,"t":"He who reaps receives wages and gathers fruit to eternal life, that both he who sows and he who reaps may rejoice together."},{"v":37,"t":"For in this the saying is true, ‘One sows, and another reaps.’"},{"v":38,"t":"I sent you to reap that for which you haven’t labored. Others have labored, and you have entered into their labor.”"},{"v":39,"t":"From that city many of the Samaritans believed in him because of the word of the woman, who testified, “He told me everything that I have done.”"},{"v":40,"t":"So when the Samaritans came to him, they begged him to stay with them. He stayed there two days."},{"v":41,"t":"Many more believed because of his word."},{"v":42,"t":"They said to the woman, “Now we believe, not because of your speaking; for we have heard for ourselves, and know that this is indeed the Christ, the Savior of the world.”"},{"v":43,"t":"After the two days he went out from there and went into Galilee."},{"v":44,"t":"For Jesus himself testified that a prophet has no honor in his own country."},{"v":45,"t":"So when he came into Galilee, the Galileans received him, having seen all the things that he did in Jerusalem at the feast, for they also went to the feast."},{"v":46,"t":"Jesus came therefore again to Cana of Galilee, where he made the water into wine. There was a certain nobleman whose son was sick at Capernaum."},{"v":47,"t":"When he heard that Jesus had come out of Judea into Galilee, he went to him and begged him that he would come down and heal his son, for he was at the point of death."},{"v":48,"t":"Jesus therefore said to him, “Unless you see signs and wonders, you will in no way believe.”"},{"v":49,"t":"The nobleman said to him, “Sir, come down before my child dies.”"},{"v":50,"t":"Jesus said to him, “Go your way. Your son lives.” The man believed the word that Jesus spoke to him, and he went his way."},{"v":51,"t":"As he was going down, his servants met him and reported, saying “Your child lives!”"},{"v":52,"t":"So he inquired of them the hour when he began to get better. They said therefore to him, “Yesterday at the seventh hour, the fever left him.”"},{"v":53,"t":"So the father knew that it was at that hour in which Jesus said to him, “Your son lives.” He believed, as did his whole house."},{"v":54,"t":"This is again the second sign that Jesus did, having come out of Judea into Galilee."}],"hr":[{"v":1,"t":"Kad Gospodin dozna da su farizeji dočuli kako on, Isus, okuplja i krsti više učenika nego Ivan -"},{"v":2,"t":"iako zapravo nije krstio sam Isus, nego njegovi učenici -"},{"v":3,"t":"ode iz Judeje i ponovno se vrati u Galileju."},{"v":4,"t":"Morao je proći kroza Samariju."},{"v":5,"t":"Dođe dakle u samarijski grad koji se zove Sihar, blizu imanja što ga Jakov dade svojemu sinu Josipu."},{"v":6,"t":"Ondje bijaše zdenac Jakovljev. Isus je umoran od puta sjedio na zdencu. Bila je otprilike šesta ura."},{"v":7,"t":"Dođe neka žena Samarijanka zahvatiti vode. Kaže joj Isus: “Daj mi piti!”"},{"v":8,"t":"Njegovi učenici bijahu otišli u grad kupiti hrane."},{"v":9,"t":"Kaže mu na to Samarijanka: “Kako ti, Židov, išteš piti od mene, Samarijanke?” Jer Židovi se ne druže sa Samarijancima."},{"v":10,"t":"Isus joj odgovori: “Kad bi znala dar Božji i tko je onaj koji ti veli: 'Daj mi piti', ti bi u njega zaiskala i on bi ti dao vode žive.”"},{"v":11,"t":"Odvrati mu žena: “Gospodine, ta nemaš ni čime bi zahvatio, a zdenac je dubok. Otkuda ti dakle voda živa?"},{"v":12,"t":"Zar si ti možda veći od oca našeg Jakova koji nam dade ovaj zdenac i sam je iz njega pio, a i sinovi njegovi i stada njegova?”"},{"v":13,"t":"Odgovori joj Isus: “Tko god pije ove vode, opet će ožednjeti."},{"v":14,"t":"A tko bude pio vode koju ću mu ja dati, ne, neće ožednjeti nikada: voda koju ću mu ja dati postat će u njemu izvorom vode koja struji u život vječni.”"},{"v":15,"t":"Kaže mu žena: “Gospodine, daj mi te vode da ne žeđam i da ne moram dolaziti ovamo zahvaćati.”"},{"v":16,"t":"Nato joj on reče: “Idi i zovi svoga muža pa se vrati ovamo.”"},{"v":17,"t":"Odgovori mu žena: “Nemam muža.” Kaže joj Isus: “Dobro si rekla: 'Nemam muža!'"},{"v":18,"t":"Pet si doista muževa imala, a ni ovaj koga sada imaš nije ti muž. To si po istini rekla.”"},{"v":19,"t":"Kaže mu žena: “Gospodine, vidim da si prorok."},{"v":20,"t":"Naši su se očevi klanjali na ovome brdu, a vi kažete da je u Jeruzalemu mjesto gdje se treba klanjati.”"},{"v":21,"t":"A Isus joj reče: “Vjeruj mi, ženo, dolazi čas kad se nećete klanjati Ocu ni na ovoj gori ni u Jeruzalemu."},{"v":22,"t":"Vi se klanjate onome što ne poznate, a mi se klanjamo onome što poznamo jer spasenje dolazi od Židova."},{"v":23,"t":"Ali dolazi čas - sada je! - kad će se istinski klanjatelji klanjati Ocu u duhu i istini jer takve upravo klanjatelje traži Otac."},{"v":24,"t":"Bog je duh i koji se njemu klanjaju, u duhu i istini treba da se klanjaju.”"},{"v":25,"t":"Kaže mu žena: “Znam da ima doći Mesija zvani Krist - Pomazanik. Kad on dođe, objavit će nam sve.”"},{"v":26,"t":"Kaže joj Isus: “Ja sam, ja koji s tobom govorim!”"},{"v":27,"t":"Uto dođu njegovi učenici pa se začude što razgovara sa ženom. Nitko ga ipak ne zapita: “Što tražiš?” ili: “Što razgovaraš s njom?”"},{"v":28,"t":"Žena ostavi svoj krčag pa ode u grad i reče ljudima:"},{"v":29,"t":"“Dođite da vidite čovjeka koji mi je kazao sve što sam počinila. Da to nije Krist?”"},{"v":30,"t":"Oni iziđu iz grada te se upute k njemu."},{"v":31,"t":"Učenici ga dotle nudili: “Učitelju, jedi!”"},{"v":32,"t":"A on im reče: “Hraniti mi se valja jelom koje vi ne poznajete.”"},{"v":33,"t":"Učenici se nato zapitkivahu: “Da mu nije tko donio jesti?”"},{"v":34,"t":"Kaže im Isus: “Jelo je moje vršiti volju onoga koji me posla i dovršiti djelo njegovo."},{"v":35,"t":"Ne govorite li vi: 'Još četiri mjeseca i evo žetve?' Gle, kažem vam, podignite oči svoje i pogledajte polja: već se bjelasaju za žetvu."},{"v":36,"t":"Žetelac već prima plaću, sabire plod za vječni život da se sijač i žetelac zajedno raduju."},{"v":37,"t":"Tu se obistinjuje izreka: 'Jedan sije, drugi žanje.'"},{"v":38,"t":"Ja vas poslah žeti ono oko čega se niste trudili; drugi su se trudili, a vi ste ušli u trud njihov.”"},{"v":39,"t":"Mnogi Samarijanci iz onoga grada povjerovaše u njega zbog riječi žene koja je svjedočila: “Kazao mi je sve što sam počinila.”"},{"v":40,"t":"Kad su dakle Samarijanci došli k njemu, moljahu ga da ostane u njih. I ostade ondje dva dana."},{"v":41,"t":"Tada ih je još mnogo više povjerovalo zbog njegove riječi"},{"v":42,"t":"pa govorahu ženi: “Sada više ne vjerujemo zbog tvoga kazivanja; ta sami smo čuli i znamo: ovo je uistinu Spasitelj svijeta.”"},{"v":43,"t":"Nakon dva dana ode odande u Galileju."},{"v":44,"t":"Sam je Isus doduše izjavio da prorok nema časti u svom zavičaju."},{"v":45,"t":"Kad je dakle stigao u Galileju, Galilejci ga lijepo primiše jer bijahu vidjeli što je sve učinio u Jeruzalemu za blagdana. Jer su i oni bili uzišli na blagdan."},{"v":46,"t":"Dođe dakle ponovno u Kanu Galilejsku, gdje bijaše pretvorio vodu u vino. Ondje bijaše neki kraljevski službenik koji je imao bolesna sina u Kafarnaumu."},{"v":47,"t":"Kad je čuo da je Isus došao iz Judeje u Galileju, ode k njemu pa ga moljaše da siđe i ozdravi mu sina jer već samo što nije umro."},{"v":48,"t":"Nato mu Isus reče: “Ako ne vidite znamenja i čudesa, ne vjerujete!”"},{"v":49,"t":"Kaže mu kraljevski službenik: “Gospodine, siđi dok mi ne umre dijete.”"},{"v":50,"t":"Kaže mu Isus: “Idi, sin tvoj živi!” Povjerova čovjek riječi koju mu reče Isus i ode."},{"v":51,"t":"Dok je on još silazio, pohite mu u susret sluge s viješću da mu sin živi."},{"v":52,"t":"Upita ih dakle za uru kad mu je krenulo nabolje. Rekoše mu: “Jučer oko sedme ure pustila ga ognjica.”"},{"v":53,"t":"Tada razabra otac da je to bilo upravo onog časa kad mu Isus reče: “Sin tvoj živi.” I povjerova on i sav dom njegov."},{"v":54,"t":"Bijaše to drugo znamenje što ga učini Isus po povratku iz Judeje u Galileju."}]},"5":{"fa":[{"v":1,"t":"و بعد از آن یهود را عیدی بود و عیسی به اورشلیم آمد."},{"v":2,"t":"و در اورشلیم نزدباب الضان حوضی است که آن را به عبرانی بیت حسدا می‌گویند که پنج رواق دارد."},{"v":3,"t":"و درآنجا جمعی کثیر از مریضان و کوران و لنگان وشلان خوابیده، منتظر حرکت آب می‌بودند."},{"v":4,"t":"و در آنجا مردی بود که سی و هشت سال به مرضی مبتلا بود."},{"v":5,"t":"چون عیسی او را خوابیده دیدو دانست که مرض او طول کشیده است، بدوگفت: «آیا می‌خواهی شفا یابی؟»"},{"v":6,"t":"مریض او راجواب داد که «ای آقا کسی ندارم که چون آب به حرکت آید، مرا در حوض بیندازد، بلکه تا وقتی که می‌آیم، دیگری پیش از من فرو رفته است."},{"v":7,"t":"عیسی بدو گفت: «برخیز و بستر خود رابرداشته، روانه شو!»"},{"v":8,"t":"که در حال آن، مرد شفایافت و بستر خود را برداشته، روانه گردید. و آن روز سبت بود."},{"v":9,"t":"پس یهودیان به آن کسی‌که شفا یافته بود، گفتند: «روز سبت است و بر تو روا نیست که بسترخود را برداری.»"},{"v":10,"t":"او در جواب ایشان گفت: «آن کسی‌که مرا شفا داد، همان به من گفت بستر خود را بردار و برو.»"},{"v":11,"t":"پس از او پرسیدند: «کیست آنکه به تو گفت، بستر خود را بردار وبرو؟»"},{"v":12,"t":"لیکن آن شفا یافته نمی دانست که بود، زیرا که عیسی ناپدید شد چون در آنجا ازدحامی بود."},{"v":13,"t":"و بعد از آن، عیسی او را در هیکل یافته بدو گفت: «اکنون شفا یافته‌ای. دیگر خطا مکن تابرای تو بدتر نگردد.»"},{"v":14,"t":"آن مرد رفت و یهودیان را خبر داد که «آنکه مرا شفا داد، عیسی است.»"},{"v":15,"t":"و از این سبب یهودیان بر عیسی تعدی می‌کردند، زیرا که این کار را در روز سبت کرده بود."},{"v":16,"t":"عیسی در جواب ایشان گفت که «پدر من تاکنون کار می‌کند و من نیز کار می‌کنم.»"},{"v":17,"t":"پس ازاین سبب، یهودیان بیشتر قصد قتل او کردند زیراکه نه‌تنها سبت را می‌شکست بلکه خدا را نیز پدرخود گفته، خود را مساوی خدا می‌ساخت."},{"v":18,"t":"آنگاه عیسی در جواب ایشان گفت: «آمین آمین به شما می‌گویم که پسر از خود هیچ نمی تواند کرد مگر آنچه بیند که پدر به عمل آرد، زیرا که آنچه او می‌کند، همچنین پسر نیز می‌کند."},{"v":19,"t":"زیرا که پدر پسر را دوست می‌دارد و هرآنچه خود می‌کند بدو می‌نماید و اعمال بزرگتر از این بدو نشان خواهد داد تا شما تعجب نمایید."},{"v":20,"t":"زیرا همچنان‌که پدر مردگان را برمی خیزاند وزنده می‌کند، همچنین پسر نیز هر‌که رامی خواهد زنده می‌کند."},{"v":21,"t":"زیرا که پدر برهیچ‌کس داوری نمی کند بلکه تمام داوری را به پسر سپرده است."},{"v":22,"t":"تا آنکه همه پسر را حرمت بدارند، همچنان‌که پدر را حرمت می‌دارند؛ وکسی‌که به پسر حرمت نکند، به پدری که او رافرستاد احترام نکرده است."},{"v":23,"t":"آمین آمین به شمامی گویم هر‌که کلام مرا بشنود و به فرستنده من ایمان آورد، حیات جاودانی دارد و در داوری نمی آید، بلکه از موت تا به حیات منتقل گشته است."},{"v":24,"t":"آمین آمین به شما می‌گویم که ساعتی می‌آید بلکه اکنون است که مردگان آواز پسر خدارا می‌شنوند و هر‌که بشنود زنده گردد."},{"v":25,"t":"زیراهمچنان‌که پدر در خود حیات دارد، همچنین پسر را نیز عطا کرده است که در خود حیات داشته باشد."},{"v":26,"t":"و بدو قدرت بخشیده است که داوری هم بکند زیرا که پسر انسان است."},{"v":27,"t":"و از این تعجب مکنید زیرا ساعتی می‌آید که در آن جمیع کسانی که در قبور می‌باشند، آواز او را خواهندشنید،"},{"v":28,"t":"و بیرون خواهند آمد؛ هر‌که اعمال نیکوکرد، برای قیامت حیات و هر‌که اعمال بد کرد، بجهت قیامت داوری."},{"v":29,"t":"من از خود هیچ نمی توانم کرد بلکه چنانکه شنیده‌ام داوری می‌کنم و داوری من عادل است زیرا که اراده خود را طالب نیستم بلکه اراده پدری که مرا فرستاده است."},{"v":30,"t":"اگر من بر خود شهادت دهم شهادت من راست نیست."},{"v":31,"t":"دیگری هست که بر من شهادت می‌دهد ومی دانم که شهادتی که او بر من می‌دهد راست است."},{"v":32,"t":"شما نزد یحیی فرستادید و او به راستی شهادت داد."},{"v":33,"t":"اما من شهادت انسان را قبول نمی کنم ولیکن این سخنان را می‌گویم تا شمانجات یابید."},{"v":34,"t":"او چراغ افروخته و درخشنده‌ای بود و شما خواستید که ساعتی به نور او شادی کنید."},{"v":35,"t":"و اما من شهادت بزرگتر از یحیی دارم زیرا آن کارهایی که پدر به من عطا کرد تا کامل کنم، یعنی‌این کارهایی که من می‌کنم، بر من شهادت می‌دهد که پدر مرا فرستاده است."},{"v":36,"t":"وخود پدر که مرا فرستاد، به من شهادت داده است که هرگز آواز او را نشنیده و صورت او راندیده‌اید،"},{"v":37,"t":"و کلام او را در خود ثابت نداریدزیرا کسی را که پدر فرستاد شما بدو ایمان نیاوردید."},{"v":38,"t":"کتب را تفتیش کنید زیرا شما گمان می‌بریدکه در آنها حیات جاودانی دارید و آنها است که به من شهادت می‌دهد."},{"v":39,"t":"و نمی خواهید نزد من آیید تا حیات یابید."},{"v":40,"t":"جلال را از مردم نمی پذیرم."},{"v":41,"t":"ولکن شما را می‌شناسم که در نفس خود محبت خدا را ندارید."},{"v":42,"t":"من به اسم پدرخود آمده‌ام و مرا قبول نمی کنید، ولی هرگاه دیگری به اسم خود آید، او را قبول خواهید کرد."},{"v":43,"t":"شما چگونه می‌توانید ایمان آرید و حال آنکه جلال از یکدیگر می‌طلبید و جلالی را که ازخدای واحد است طالب نیستید؟"},{"v":44,"t":"گمان مبریدکه من نزد پدر بر شما ادعا خواهم کرد. کسی هست که مدعی شما می‌باشد و آن موسی است که بر او امیدوار هستید."},{"v":45,"t":"زیرا اگر موسی راتصدیق می‌کردید، مرا نیز تصدیق می‌کردیدچونکه او درباره من نوشته است."},{"v":46,"t":"اما چون نوشته های او را تصدیق نمی کنید، پس چگونه سخنهای مرا قبول خواهید کرد.»"}],"en":[{"v":1,"t":"After these things, there was a feast of the Jews, and Jesus went up to Jerusalem."},{"v":2,"t":"Now in Jerusalem by the sheep gate, there is a pool, which is called in Hebrew, “Bethesda”, having five porches."},{"v":3,"t":"In these lay a great multitude of those who were sick, blind, lame, or paralyzed, waiting for the moving of the water;"},{"v":4,"t":"for an angel went down at certain times into the pool and stirred up the water. Whoever stepped in first after the stirring of the water was healed of whatever disease he had."},{"v":5,"t":"A certain man was there who had been sick for thirty-eight years."},{"v":6,"t":"When Jesus saw him lying there, and knew that he had been sick for a long time, he asked him, “Do you want to be made well?”"},{"v":7,"t":"The sick man answered him, “Sir, I have no one to put me into the pool when the water is stirred up, but while I’m coming, another steps down before me.”"},{"v":8,"t":"Jesus said to him, “Arise, take up your mat, and walk.”"},{"v":9,"t":"Immediately, the man was made well, and took up his mat and walked. Now that day was a Sabbath."},{"v":10,"t":"So the Jews said to him who was cured, “It is the Sabbath. It is not lawful for you to carry the mat.”"},{"v":11,"t":"He answered them, “He who made me well said to me, ‘Take up your mat and walk.’ ”"},{"v":12,"t":"Then they asked him, “Who is the man who said to you, ‘Take up your mat and walk’?”"},{"v":13,"t":"But he who was healed didn’t know who it was, for Jesus had withdrawn, a crowd being in the place."},{"v":14,"t":"Afterward Jesus found him in the temple and said to him, “Behold, you are made well. Sin no more, so that nothing worse happens to you.”"},{"v":15,"t":"The man went away, and told the Jews that it was Jesus who had made him well."},{"v":16,"t":"For this cause the Jews persecuted Jesus and sought to kill him, because he did these things on the Sabbath."},{"v":17,"t":"But Jesus answered them, “My Father is still working, so I am working, too.”"},{"v":18,"t":"For this cause therefore the Jews sought all the more to kill him, because he not only broke the Sabbath, but also called God his own Father, making himself equal with God."},{"v":19,"t":"Jesus therefore answered them, “Most certainly, I tell you, the Son can do nothing of himself, but what he sees the Father doing. For whatever things he does, these the Son also does likewise."},{"v":20,"t":"For the Father has affection for the Son, and shows him all things that he himself does. He will show him greater works than these, that you may marvel."},{"v":21,"t":"For as the Father raises the dead and gives them life, even so the Son also gives life to whom he desires."},{"v":22,"t":"For the Father judges no one, but he has given all judgment to the Son,"},{"v":23,"t":"that all may honor the Son, even as they honor the Father. He who doesn’t honor the Son doesn’t honor the Father who sent him."},{"v":24,"t":"“Most certainly I tell you, he who hears my word and believes him who sent me has eternal life, and doesn’t come into judgment, but has passed out of death into life."},{"v":25,"t":"Most certainly I tell you, the hour comes, and now is, when the dead will hear the Son of God’s voice; and those who hear will live."},{"v":26,"t":"For as the Father has life in himself, even so he gave to the Son also to have life in himself."},{"v":27,"t":"He also gave him authority to execute judgment, because he is a son of man."},{"v":28,"t":"Don’t marvel at this, for the hour comes in which all who are in the tombs will hear his voice"},{"v":29,"t":"and will come out; those who have done good, to the resurrection of life; and those who have done evil, to the resurrection of judgment."},{"v":30,"t":"I can of myself do nothing. As I hear, I judge; and my judgment is righteous, because I don’t seek my own will, but the will of my Father who sent me."},{"v":31,"t":"“If I testify about myself, my witness is not valid."},{"v":32,"t":"It is another who testifies about me. I know that the testimony which he testifies about me is true."},{"v":33,"t":"You have sent to John, and he has testified to the truth."},{"v":34,"t":"But the testimony which I receive is not from man. However, I say these things that you may be saved."},{"v":35,"t":"He was the burning and shining lamp, and you were willing to rejoice for a while in his light."},{"v":36,"t":"But the testimony which I have is greater than that of John; for the works which the Father gave me to accomplish, the very works that I do, testify about me, that the Father has sent me."},{"v":37,"t":"The Father himself, who sent me, has testified about me. You have neither heard his voice at any time, nor seen his form."},{"v":38,"t":"You don’t have his word living in you, because you don’t believe him whom he sent."},{"v":39,"t":"“You search the Scriptures, because you think that in them you have eternal life; and these are they which testify about me."},{"v":40,"t":"Yet you will not come to me, that you may have life."},{"v":41,"t":"I don’t receive glory from men."},{"v":42,"t":"But I know you, that you don’t have God’s love in yourselves."},{"v":43,"t":"I have come in my Father’s name, and you don’t receive me. If another comes in his own name, you will receive him."},{"v":44,"t":"How can you believe, who receive glory from one another, and you don’t seek the glory that comes from the only God?"},{"v":45,"t":"“Don’t think that I will accuse you to the Father. There is one who accuses you, even Moses, on whom you have set your hope."},{"v":46,"t":"For if you believed Moses, you would believe me; for he wrote about me."},{"v":47,"t":"But if you don’t believe his writings, how will you believe my words?”"}],"hr":[{"v":1,"t":"Nakon toga bijaše židovski blagdan pa Isus uziđe u Jeruzalem."},{"v":2,"t":"U Jeruzalemu se kod Ovčjih vrata nalazi kupalište koje se hebrejski zove Bethzatha, a ima pet trijemova."},{"v":3,"t":"U njima je ležalo mnoštvo bolesnika - slijepih, hromih, uzetih:čekali su da izbije voda.."},{"v":4,"t":"Anđeo bi Gospodnji, naime, silazio od vremena do vremena u ribnjak i pokrenuo vodu: tko bi prvi ušao pošto je voda izbila, ozdravio bi makar bolovao od bilo kakve bolesti."},{"v":5,"t":"Bijaše ondje neki čovjek koji je trpio od svoje bolesti trideset i osam godina."},{"v":6,"t":"Kad ga Isus opazi gdje leži i kada dozna da je već dugo u tome stanju, kaže mu: “Želiš li ozdraviti?”"},{"v":7,"t":"Odgovori mu bolesnik: “Gospodine, nikoga nemam tko bi me uronio u kupalište kad se voda uzbiba. Dok ja stignem, drugi već prije mene siđe.”"},{"v":8,"t":"Kaže mu Isus: “Ustani, uzmi svoju postelju i hodi!”"},{"v":9,"t":"Čovjek odmah ozdravi, uzme svoju postelju i prohoda. Toga dana bijaše subota."},{"v":10,"t":"Židovi su stoga govorili ozdravljenomu: “Subota je! Ne smiješ nositi postelju svoju!”"},{"v":11,"t":"On im odvrati: “Onaj koji me ozdravi reče mi: 'Uzmi svoju postelju i hodi!'”"},{"v":12,"t":"Upitaše ga dakle: “Tko je taj čovjek koji ti je rekao: 'Uzmi i hodi?'”"},{"v":13,"t":"No ozdravljenik nije znao tko je taj jer je Isus nestao u mnoštvu što se ondje nalazilo."},{"v":14,"t":"Nakon toga nađe ga Isus u Hramu i reče mu: “Eto, ozdravio si! Više ne griješi da te što gore ne snađe!”"},{"v":15,"t":"Čovjek ode i javi Židovima da je Isus onaj koji ga je ozdravio."},{"v":16,"t":"Zbog toga su Židovi počeli Isusa napadati što to radi subotom."},{"v":17,"t":"Isus im odgovori: “Otac moj sve do sada radi pa i ja radim.”"},{"v":18,"t":"Zbog toga su Židovi još više gledali da ga ubiju jer je ne samo kršio subotu nego i Boga nazivao Ocem svojim izjednačujući sebe s Bogom."},{"v":19,"t":"Isus nato odvrati: “Zaista, zaista, kažem vam: Sin ne može sam od sebe činiti ništa, doli što vidi da čini Otac; što on čini, to jednako i Sin čini."},{"v":20,"t":"Jer Otac Ljubi Sina i pokazuje mu sve što sam čini. Pokazat će mu i veća djela od ovih te ćete se čudom čuditi."},{"v":21,"t":"Uistinu, kao što Otac uskrisuje mrtve i oživljava tako i Sin oživljava koje hoće."},{"v":22,"t":"Otac doista ne sudi nikomu: sav je sud predao Sinu"},{"v":23,"t":"da svi časte Sina kao što časte Oca. Tko ne časti Sina, ne časti ni Oca koji ga posla.”"},{"v":24,"t":"“Zaista, zaista, kažem vam: tko sluša moju riječ i vjeruje onomu koji me posla, ima život vječni i ne dolazi na sud, nego je prešao iz smrti u život."},{"v":25,"t":"Zaista, zaista, kažem vam: dolazi čas - sada je! - kad će mrtvi čuti glas Sina Božjega i koji čuju, živjet će."},{"v":26,"t":"Doista, kao što Otac ima život u sebi tako je i Sinu dao da ima život u sebi;"},{"v":27,"t":"i ovlasti ga da sudi jer je Sin Čovječji."},{"v":28,"t":"Ne čudite se tome jer dolazi čas kad će svi koji su u grobovima, čuti njegov glas."},{"v":29,"t":"I izići će: koji su dobro činili - na uskrsnuće života, a koji su radili zlo - na uskrsnuće osude."},{"v":30,"t":"Ja sam od sebe ne mogu učiniti ništa: kako čujem, sudim, i sud je moj pravedan jer ne tražim svoje volje, nego volju onoga koji me posla.”"},{"v":31,"t":"“Ako ja svjedočim sam za sebe, svjedočanstvo moje nije istinito."},{"v":32,"t":"Drugi svjedoči za mene i znam: istinito je svjedočanstvo kojim on svjedoči za mene."},{"v":33,"t":"Vi ste poslali k Ivanu i on je posvjedočio za istinu."},{"v":34,"t":"Ja ne primam svjedočanstva od čovjeka, već govorim to da se vi spasite."},{"v":35,"t":"On bijaše svjetiljka što gori i svijetli, a vi se htjedoste samo za čas naslađivati njegovom svjetlosti."},{"v":36,"t":"Ali ja imam svjedočanstvo veće od Ivanova: djela koja mi je dao izvršiti Otac, upravo ta djela koja činim, svjedoče za mene - da me poslao Otac."},{"v":37,"t":"Pa i Otac koji me posla sam je svjedočio za mene. Niti ste glasa njegova ikada čuli niti ste lica njegova ikada vidjeli,"},{"v":38,"t":"a ni riječ njegova ne prebiva u vama jer ne vjerujete onomu kojega on posla."},{"v":39,"t":"Vi istražujete Pisma jer mislite po njima imati život vječni. I ona svjedoče za mene,"},{"v":40,"t":"a vi ipak nećete da dođete k meni da život imate."},{"v":41,"t":"Slave od ljudi ne tražim,"},{"v":42,"t":"ali vas dobro upoznah: ljubavi Božje nemate u sebi."},{"v":43,"t":"Ja sam došao u ime Oca svoga i vi me ne primate. Dođe li tko drugi u svoje ime, njega ćete primiti."},{"v":44,"t":"Ta kako biste vi vjerovali kad tražite slavu jedni od drugih, a slave od Boga jedinoga ne tražite!"},{"v":45,"t":"Ne mislite da ću vas ja tužiti Ocu. Vaš je tužitelj Mojsije u koga se uzdate."},{"v":46,"t":"Uistinu, kad biste vjerovali Mojsiju, i meni biste vjerovali: ta o meni je on pisao."},{"v":47,"t":"Ali ako njegovim pismima ne vjerujete, kako da mojim riječima vjerujete?”"}]},"6":{"fa":[{"v":1,"t":"و بعد از آن عیسی به آن طرف دریای جلیل که دریای طبریه باشد، رفت."},{"v":2,"t":"و جمعی کثیر از عقب او آمدند زیرا آن معجزاتی را که به مریضان می‌نمود، می‌دیدند."},{"v":3,"t":"آنگاه عیسی به کوهی برآمده، با شاگردان خود در آنجا بنشست."},{"v":4,"t":"و فصح که عید یهود باشد، نزدیک بود."},{"v":5,"t":"پس عیسی چشمان خود را بالا انداخته، دیدکه جمعی کثیر به طرف او می‌آیند. به فیلپس گفت: «از کجا نان بخریم تا اینها بخورند؟»"},{"v":6,"t":"و این را از روی امتحان به او گفت، زیرا خود می‌دانست چه باید کرد."},{"v":7,"t":"فیلپس او را جواب داد که «دویست دینار نان، اینها را کفایت نکند تا هر یک اندکی بخورند!»"},{"v":8,"t":"یکی از شاگردانش که اندریاس برادر شمعون پطرس باشد، وی را گفت:"},{"v":9,"t":"«دراینجا پسری است که پنج نان جو و دو ماهی دارد. و لیکن این از برای این گروه چه می‌شود؟»"},{"v":10,"t":"عیسی گفت: «مردم را بنشانید.» و در آن مکان، گیاه بسیار بود، و آن گروه قریب به پنج هزار مردبودند که نشستند."},{"v":11,"t":"عیسی نانها را گرفته و شکرنموده، به شاگردان داد و شاگردان به نشستگان دادند؛ و همچنین از دو ماهی نیز به قدری که خواستند."},{"v":12,"t":"و چون سیر گشتند، به شاگردان خود گفت: «پاره های باقی‌مانده را جمع کنید تاچیزی ضایع نشود.»"},{"v":13,"t":"پس جمع کردند و ازپاره های پنج نان جو که از خورندگان زیاده آمده بود، دوازده سبد پر کردند."},{"v":14,"t":"و چون مردمان این معجزه را که از عیسی صادر شده بود دیدند، گفتند که «این البته همان نبی است که باید در جهان بیاید!»"},{"v":15,"t":"و اما عیسی چون دانست که می‌خواهند بیایند و او را به زور برده پادشاه سازند، باز تنها به کوه برآمد."},{"v":16,"t":"و چون شام شد، شاگردانش به‌جانب دریاپایین رفتند،"},{"v":17,"t":"و به کشتی سوار شده به آن طرف دریا به کفرناحوم روانه شدند. و چون تاریک شدعیسی هنوز نزد ایشان نیامده بود."},{"v":18,"t":"و دریابواسطه وزیدن باد شدید به تلاطم آمد."},{"v":19,"t":"پس وقتی که قریب به بیست و پنج یا سی تیر پرتاپ رانده بودند، عیسی را دیدند که بر روی دریاخرامان شده، نزدیک کشتی می‌آید. پس ترسیدند."},{"v":20,"t":"او بدیشان گفت: «من هستم، مترسید!»"},{"v":21,"t":"و چون می‌خواستند او را در کشتی بیاورند، در ساعت کشتی به آن زمینی که عازم آن بودند رسید."},{"v":22,"t":"بامدادان گروهی که به آن طرف دریا ایستاده بودند، دیدند که هیچ زورقی نبود غیر از آن که شاگردان او داخل آن شده بودند و عیسی باشاگردان خود داخل آن زورق نشده، بلکه شاگردانش تنها رفته بودند."},{"v":23,"t":"لیکن زورقهای دیگر از طبریه آمد، نزدیک به آنجایی که نان خورده بودند بعد از آنکه خداوند شکر گفته بود."},{"v":24,"t":"پس چون آن گروه دیدند که عیسی وشاگردانش در آنجا نیستند، ایشان نیز به کشتیهاسوار شده، در طلب عیسی به کفرناحوم آمدند."},{"v":25,"t":"و چون او را در آن طرف دریا یافتند، بدوگفتند: «ای استاد کی به اینجا آمدی؟»"},{"v":26,"t":"عیسی در جواب ایشان گفت: «آمین آمین به شمامی گویم که مرا می‌طلبید نه بسبب معجزاتی که دیدید، بلکه بسبب آن نان که خوردید و سیرشدید."},{"v":27,"t":"کار بکنید نه برای خوراک فانی بلکه برای خوراکی که تا حیات جاودانی باقی است که پسر انسان آن را به شما عطا خواهد کرد، زیراخدای پدر بر او مهر زده است.»"},{"v":28,"t":"بدو گفتند: «چه کنیم تا اعمال خدا را به‌جا آورده باشیم؟»"},{"v":29,"t":"عیسی در جواب ایشان گفت: «عمل خدا این است که به آن کسی‌که او فرستاد، ایمان بیاورید.»"},{"v":30,"t":"بدو گفتند: «چه معجزه می‌نمایی تا آن را دیده به تو ایمان آوریم؟ چکار می‌کنی؟"},{"v":31,"t":"پدران ما دربیابان من را خوردند، چنانکه مکتوب است که ازآسمان بدیشان نان عطا کرد تا بخورند.»"},{"v":32,"t":"عیسی بدیشان گفت: «آمین آمین به شما می‌گویم که موسی نان را از آسمان به شما نداد، بلکه پدر من نان حقیقی را از آسمان به شما می‌دهد."},{"v":33,"t":"زیرا که نان خدا آن است که از آسمان نازل شده، به جهان حیات می‌بخشد.»"},{"v":34,"t":"آنگاه بدو گفتند: «ای خداوند این نان را پیوسته به ما بده.»"},{"v":35,"t":"عیسی بدیشان گفت: «من نان حیات هستم. کسی‌که نزد من آید، هرگز گرسنه نشود و هر‌که به من ایمان آرد هرگز تشنه نگردد."},{"v":36,"t":"لیکن به شماگفتم که مرا هم دیدید و ایمان نیاوردید."},{"v":37,"t":"هرآنچه پدر به من عطا کند، به‌جانب من آید و هر‌که به‌جانب من آید، او را بیرون نخواهم نمود."},{"v":38,"t":"زیرا از آسمان نزول کردم نه تا به اراده خودعمل کنم، بلکه به اراده فرستنده خود."},{"v":39,"t":"و اراده پدری که مرا فرستاد این است که از آنچه به من عطا کرد چیزی تلف نکنم بلکه در روز بازپسین آن را برخیزانم."},{"v":40,"t":"و اراده فرستنده من این است که هر‌که پسر را دید و بدو ایمان آورد، حیات جاودانی داشته باشد و من در روز بازپسین او راخواهم برخیزانید.»"},{"v":41,"t":"پس یهودیان درباره او همهمه کردند زیراگفته بود: «من هستم آن نانی که از آسمان نازل شد.»"},{"v":42,"t":"و گفتند: «آیا این عیسی پسر یوسف نیست که ما پدر و مادر او را می‌شناسیم؟ پس چگونه می‌گوید که از آسمان نازل شدم؟»"},{"v":43,"t":"عیسی در جواب ایشان گفت: «با یکدیگرهمهمه مکنید."},{"v":44,"t":"کسی نمی تواند نزد من آید، مگر آنکه پدری که مرا فرستاد او را جذب کند ومن در روز بازپسین او را خواهم برخیزانید."},{"v":45,"t":"درانبیا مکتوب است که همه از خدا تعلیم خواهندیافت. پس هر‌که از پدر شنید و تعلیم یافت نزد من می‌آید."},{"v":46,"t":"نه اینکه کسی پدر را دیده باشد، جزآن کسی‌که از جانب خداست، او پدر را دیده است."},{"v":47,"t":"آمین آمین به شما می‌گویم هر‌که به من ایمان آرد، حیات جاودانی دارد."},{"v":48,"t":"من نان حیات هستم."},{"v":49,"t":"پدران شما در بیابان من را خوردند ومردند."},{"v":50,"t":"این نانی است که از آسمان نازل شد تاهر‌که از آن بخورد نمیرد."},{"v":51,"t":"من هستم آن نان زنده که از آسمان نازل شد. اگر کسی از این نان بخورد تا به ابد زنده خواهد ماند و نانی که من عطامی کنم جسم من است که آن را بجهت حیات جهان می‌بخشم.»"},{"v":52,"t":"پس یهودیان با یکدیگر مخاصمه کرده، می‌گفتند: «چگونه این شخص می‌تواند جسدخود را به ما دهد تا بخوریم؟»"},{"v":53,"t":"عیسی بدیشان گفت: «آمین آمین به شما می‌گویم اگر جسد پسرانسان را نخورید و خون او را ننوشید، در خودحیات ندارید."},{"v":54,"t":"و هر‌که جسد مرا خورد و خون مرا نوشید، حیات جاودانی دارد و من در روزآخر او را خواهم برخیزانید."},{"v":55,"t":"زیرا که جسد من، خوردنی حقیقی و خون من، آشامیدنی حقیقی است."},{"v":56,"t":"پس هر‌که جسد مرا می‌خورد و خون مرا می‌نوشد، در من می‌ماند و من در او."},{"v":57,"t":"چنانکه پدر زنده مرا فرستاد و من به پدر زنده هستم، همچنین کسی‌که مرا بخورد او نیز به من زنده می‌شود."},{"v":58,"t":"این است نانی که از آسمان نازل شد، نه همچنان‌که پدران شما من را خوردند و مردند؛ بلکه هر‌که این نان را بخورد تا به ابد زنده ماند.»"},{"v":59,"t":"این سخن را وقتی که در کفرناحوم تعلیم می‌داد، در کنیسه گفت."},{"v":60,"t":"آنگاه بسیاری از شاگردان او چون این راشنیدند گفتند: «این کلام سخت است! که می‌تواندآن را بشنود؟»"},{"v":61,"t":"چون عیسی در خود دانست که شاگردانش در این امر همهمه می‌کنند، بدیشان گفت: «آیا این شما را لغزش می‌دهد؟"},{"v":62,"t":"پس اگرپسر انسان را بینید که به‌جایی که اول بود صعودمی کند چه؟"},{"v":63,"t":"روح است که زنده می‌کند و اما ازجسد فایده‌ای نیست. کلامی را که من به شمامی گویم روح و حیات‌است."},{"v":64,"t":"ولیکن بعضی از شما هستند که ایمان نمی آورند.» زیرا که عیسی از ابتدا می‌دانست کیانند که ایمان نمی آورند وکیست که او را تسلیم خواهد کرد."},{"v":65,"t":"پس گفت: «از این سبب به شما گفتم که کسی نزد من نمی تواند آمد مگر آنکه پدر من، آن را بدو عطاکند.»"},{"v":66,"t":"در همان وقت بسیاری از شاگردان اوبرگشته، دیگر با او همراهی نکردند."},{"v":67,"t":"آنگاه عیسی به آن دوازده گفت: «آیا شمانیز می‌خواهید بروید؟»"},{"v":68,"t":"شمعون پطرس به اوجواب داد: «خداوندا نزد که برویم؟ کلمات حیات جاودانی نزد تو است."},{"v":69,"t":"و ما ایمان آورده و شناخته‌ایم که تو مسیح پسر خدای حی هستی.»"},{"v":70,"t":"عیسی بدیشان جواب داد: «آیا من شما دوازده را برنگزیدم و حال آنکه یکی از شماابلیسی است.»"},{"v":71,"t":"و این را درباره یهودا پسرشمعون اسخریوطی گفت، زیرا او بود که می‌بایست تسلیم‌کننده وی بشود و یکی از آن دوازده بود."}],"en":[{"v":1,"t":"After these things, Jesus went away to the other side of the sea of Galilee, which is also called the Sea of Tiberias."},{"v":2,"t":"A great multitude followed him, because they saw his signs which he did on those who were sick."},{"v":3,"t":"Jesus went up into the mountain, and he sat there with his disciples."},{"v":4,"t":"Now the Passover, the feast of the Jews, was at hand."},{"v":5,"t":"Jesus therefore, lifting up his eyes and seeing that a great multitude was coming to him, said to Philip, “Where are we to buy bread, that these may eat?”"},{"v":6,"t":"He said this to test him, for he himself knew what he would do."},{"v":7,"t":"Philip answered him, “Two hundred denarii worth of bread is not sufficient for them, that every one of them may receive a little.”"},{"v":8,"t":"One of his disciples, Andrew, Simon Peter’s brother, said to him,"},{"v":9,"t":"“There is a boy here who has five barley loaves and two fish, but what are these among so many?”"},{"v":10,"t":"Jesus said, “Have the people sit down.” Now there was much grass in that place. So the men sat down, in number about five thousand."},{"v":11,"t":"Jesus took the loaves, and having given thanks, he distributed to the disciples, and the disciples to those who were sitting down, likewise also of the fish as much as they desired."},{"v":12,"t":"When they were filled, he said to his disciples, “Gather up the broken pieces which are left over, that nothing be lost.”"},{"v":13,"t":"So they gathered them up, and filled twelve baskets with broken pieces from the five barley loaves, which were left over by those who had eaten."},{"v":14,"t":"When therefore the people saw the sign which Jesus did, they said, “This is truly the prophet who comes into the world.”"},{"v":15,"t":"Jesus therefore, perceiving that they were about to come and take him by force to make him king, withdrew again to the mountain by himself."},{"v":16,"t":"When evening came, his disciples went down to the sea."},{"v":17,"t":"They entered into the boat, and were going over the sea to Capernaum. It was now dark, and Jesus had not come to them."},{"v":18,"t":"The sea was tossed by a great wind blowing."},{"v":19,"t":"When therefore they had rowed about twenty-five or thirty stadia, they saw Jesus walking on the sea and drawing near to the boat; and they were afraid."},{"v":20,"t":"But he said to them, “It is I. Don’t be afraid.”"},{"v":21,"t":"They were willing therefore to receive him into the boat. Immediately the boat was at the land where they were going."},{"v":22,"t":"On the next day, the multitude that stood on the other side of the sea saw that there was no other boat there, except the one in which his disciples had embarked, and that Jesus hadn’t entered with his disciples into the boat, but his disciples had gone away alone."},{"v":23,"t":"However, boats from Tiberias came near to the place where they ate the bread after the Lord had given thanks."},{"v":24,"t":"When the multitude therefore saw that Jesus wasn’t there, nor his disciples, they themselves got into the boats and came to Capernaum, seeking Jesus."},{"v":25,"t":"When they found him on the other side of the sea, they asked him, “Rabbi, when did you come here?”"},{"v":26,"t":"Jesus answered them, “Most certainly I tell you, you seek me, not because you saw signs, but because you ate of the loaves and were filled."},{"v":27,"t":"Don’t work for the food which perishes, but for the food which remains to eternal life, which the Son of Man will give to you. For God the Father has sealed him.”"},{"v":28,"t":"They said therefore to him, “What must we do, that we may work the works of God?”"},{"v":29,"t":"Jesus answered them, “This is the work of God, that you believe in him whom he has sent.”"},{"v":30,"t":"They said therefore to him, “What then do you do for a sign, that we may see and believe you? What work do you do?"},{"v":31,"t":"Our fathers ate the manna in the wilderness. As it is written, ‘He gave them bread out of heaven to eat.’”"},{"v":32,"t":"Jesus therefore said to them, “Most certainly, I tell you, it wasn’t Moses who gave you the bread out of heaven, but my Father gives you the true bread out of heaven."},{"v":33,"t":"For the bread of God is that which comes down out of heaven and gives life to the world.”"},{"v":34,"t":"They said therefore to him, “Lord, always give us this bread.”"},{"v":35,"t":"Jesus said to them, “I am the bread of life. Whoever comes to me will not be hungry, and whoever believes in me will never be thirsty."},{"v":36,"t":"But I told you that you have seen me, and yet you don’t believe."},{"v":37,"t":"All those whom the Father gives me will come to me. He who comes to me I will in no way throw out."},{"v":38,"t":"For I have come down from heaven, not to do my own will, but the will of him who sent me."},{"v":39,"t":"This is the will of my Father who sent me, that of all he has given to me I should lose nothing, but should raise him up at the last day."},{"v":40,"t":"This is the will of the one who sent me, that everyone who sees the Son and believes in him should have eternal life; and I will raise him up at the last day.”"},{"v":41,"t":"The Jews therefore murmured concerning him, because he said, “I am the bread which came down out of heaven.”"},{"v":42,"t":"They said, “Isn’t this Jesus, the son of Joseph, whose father and mother we know? How then does he say, ‘I have come down out of heaven’?”"},{"v":43,"t":"Therefore Jesus answered them, “Don’t murmur among yourselves."},{"v":44,"t":"No one can come to me unless the Father who sent me draws him; and I will raise him up in the last day."},{"v":45,"t":"It is written in the prophets, ‘They will all be taught by God.’ Therefore everyone who hears from the Father and has learned, comes to me."},{"v":46,"t":"Not that anyone has seen the Father, except he who is from God. He has seen the Father."},{"v":47,"t":"Most certainly, I tell you, he who believes in me has eternal life."},{"v":48,"t":"I am the bread of life."},{"v":49,"t":"Your fathers ate the manna in the wilderness and they died."},{"v":50,"t":"This is the bread which comes down out of heaven, that anyone may eat of it and not die."},{"v":51,"t":"I am the living bread which came down out of heaven. If anyone eats of this bread, he will live forever. Yes, the bread which I will give for the life of the world is my flesh.”"},{"v":52,"t":"The Jews therefore contended with one another, saying, “How can this man give us his flesh to eat?”"},{"v":53,"t":"Jesus therefore said to them, “Most certainly I tell you, unless you eat the flesh of the Son of Man and drink his blood, you don’t have life in yourselves."},{"v":54,"t":"He who eats my flesh and drinks my blood has eternal life, and I will raise him up at the last day."},{"v":55,"t":"For my flesh is food indeed, and my blood is drink indeed."},{"v":56,"t":"He who eats my flesh and drinks my blood lives in me, and I in him."},{"v":57,"t":"As the living Father sent me, and I live because of the Father, so he who feeds on me will also live because of me."},{"v":58,"t":"This is the bread which came down out of heaven—not as our fathers ate the manna and died. He who eats this bread will live forever.”"},{"v":59,"t":"He said these things in the synagogue, as he taught in Capernaum."},{"v":60,"t":"Therefore many of his disciples, when they heard this, said, “This is a hard saying! Who can listen to it?”"},{"v":61,"t":"But Jesus knowing in himself that his disciples murmured at this, said to them, “Does this cause you to stumble?"},{"v":62,"t":"Then what if you would see the Son of Man ascending to where he was before?"},{"v":63,"t":"It is the spirit who gives life. The flesh profits nothing. The words that I speak to you are spirit, and are life."},{"v":64,"t":"But there are some of you who don’t believe.” For Jesus knew from the beginning who they were who didn’t believe, and who it was who would betray him."},{"v":65,"t":"He said, “For this cause I have said to you that no one can come to me, unless it is given to him by my Father.”"},{"v":66,"t":"At this, many of his disciples went back and walked no more with him."},{"v":67,"t":"Jesus said therefore to the twelve, “You don’t also want to go away, do you?”"},{"v":68,"t":"Simon Peter answered him, “Lord, to whom would we go? You have the words of eternal life."},{"v":69,"t":"We have come to believe and know that you are the Christ, the Son of the living God.”"},{"v":70,"t":"Jesus answered them, “Didn’t I choose you, the twelve, and one of you is a devil?”"},{"v":71,"t":"Now he spoke of Judas, the son of Simon Iscariot, for it was he who would betray him, being one of the twelve."}],"hr":[{"v":1,"t":"Nakon toga ode Isus na drugu stranu Galilejskog, Tiberijadskog mora."},{"v":2,"t":"Slijedilo ga silno mnoštvo jer su gledali znamenja što ih je činio na bolesnicima."},{"v":3,"t":"A Isus uziđe na goru i ondje sjeđaše sa svojim učenicima."},{"v":4,"t":"Bijaše blizu Pasha, židovski blagdan."},{"v":5,"t":"Isus podigne oči i ugleda kako silan svijet dolazi k njemu pa upita Filipa: “Gdje da kupimo kruha da ovi blaguju?”"},{"v":6,"t":"To reče kušajući ga; jer znao je što će učiniti."},{"v":7,"t":"Odgovori mu Filip: “Za dvjesta denara kruha ne bi bilo dosta da svaki nešto malo dobije.”"},{"v":8,"t":"Kaže mu jedan od njegovih učenika, Andrija, brat Šimuna Petra:"},{"v":9,"t":"“Ovdje je dječak koji ima pet ječmenih kruhova i dvije ribice! Ali što je to za tolike?”"},{"v":10,"t":"Reče Isus: “Neka ljudi posjedaju!” A bilo je mnogo trave na tome mjestu. Posjedaše dakle muškarci, njih oko pet tisuća."},{"v":11,"t":"Isus uze kruhove, izreče zahvalnicu pa razdijeli onima koji su posjedali. A tako i od ribica - koliko su god htjeli."},{"v":12,"t":"A kad se nasitiše, reče svojim učenicima: “Skupite preostale ulomke da ništa ne propadne!”"},{"v":13,"t":"Skupili su dakle i napunili dvanaest košara ulomaka što od pet ječmenih kruhova pretekoše onima koji su blagovali."},{"v":14,"t":"Kad su ljudi vidjeli znamenje što ga Isus učini, rekoše: “Ovo je uistinu Prorok koji ima doći na svijet!”"},{"v":15,"t":"Kad Isus spozna da kane doći, pograbiti ga i zakraljiti, povuče se ponovno u goru, posve sam."},{"v":16,"t":"Kad nasta večer, siđoše njegovi učenici k moru,"},{"v":17,"t":"uđoše u lađicu i krenuše na onu stranu mora, u Kafarnaum. Već se i smrklo, a Isusa još nikako k njima."},{"v":18,"t":"More se uzburkalo od silnog vjetra što je zapuhao."},{"v":19,"t":"Pošto su dakle isplovili oko dvadeset i pet do trideset stadija, ugledaju Isusa gdje ide po moru i približava se lađici. Prestraše se,"},{"v":20,"t":"a on će njima: “Ja sam! Ne bojte se!”"},{"v":21,"t":"Htjedoše ga uzeti u lađicu, kadli se lađica odmah nađe na obali kamo su se zaputili."},{"v":22,"t":"Sutradan mnoštvo, koje osta s onu stranu mora, zapazi da ondje bijaše samo jedna lađica i da Isus nije bio ušao zajedno sa svojim učenicima u lađicu, nego da oni odoše sami."},{"v":23,"t":"Iz Tiberijade pak stigoše druge lađice blizu onog mjesta gdje jedoše kruh pošto je Gospodin izrekao zahvalnicu."},{"v":24,"t":"Kada dakle mnoštvo vidje da ondje nema Isusa ni njegovih učenika, uđu u lađice i odu u Kafarnaum tražeći Isusa."},{"v":25,"t":"Kad ga nađoše s onu stranu mora, rekoše mu: “Učitelju, kad si ovamo došao?”"},{"v":26,"t":"Isus im odgovori: “Zaista, zaista, kažem vam: tražite me, ali ne stoga što vidjeste znamenja, nego stoga što ste jeli od onih kruhova i nasitili se."},{"v":27,"t":"Radite, ali ne za hranu propadljivu, nego za hranu koja ostaje za život vječni: nju će vam dati Sin Čovječji jer njega Otac - Bog - opečati.”"},{"v":28,"t":"Rekoše mu dakle: “Što nam je činiti da bismo radili djela Božja?”"},{"v":29,"t":"Odgovori im Isus: “Djelo je Božje da vjerujete u onoga kojega je on poslao.”"},{"v":30,"t":"Rekoše mu onda: “Kakvo ti znamenje činiš da vidimo pa da ti vjerujemo? Koje je tvoje djelo?"},{"v":31,"t":"Očevi naši blagovaše manu u pustinji, kao što je pisano: Nahrani ih kruhom nebeskim.”"},{"v":32,"t":"Reče im Isus: “Zaista, zaista, kažem vam: nije vam Mojsije dao kruh s neba, nego Otac moj daje vam kruh s neba, kruh istinski;"},{"v":33,"t":"jer kruh je Božji Onaj koji silazi s neba i daje život svijetu.”"},{"v":34,"t":"Rekoše mu nato: “Gospodine, daj nam uvijek toga kruha.”"},{"v":35,"t":"Reče im Isus: “Ja sam kruh života. Tko dolazi k meni, neće ogladnjeti; tko vjeruje u mene, neće ožednjeti nikada."},{"v":36,"t":"No rekoh vam: vidjeli ste me, a opet ne vjerujete."},{"v":37,"t":"Svi koje mi daje Otac doći će k meni, i onoga tko dođe k meni neću izbaciti;"},{"v":38,"t":"jer siđoh s neba ne da vršim svoju volju, nego volju onoga koji me posla."},{"v":39,"t":"A ovo je volja onoga koji me posla: da nikoga od onih koje mi je dao ne izgubim, nego da ih uskrisim u posljednji dan."},{"v":40,"t":"Da, to je volja Oca mojega da tko god vidi Sina i vjeruje u njega, ima život vječni i ja da ga uskrisim u posljednji dan.”"},{"v":41,"t":"Židovi nato mrmljahu protiv njega što je rekao: “Ja sam kruh koji je sišao s neba.”"},{"v":42,"t":"Govorahu: “Nije li to Isus, sin Josipov? Ne poznajemo li mu oca i majku? Kako sada govori: 'Sišao sam s neba?'”"},{"v":43,"t":"Isus im odvrati: “Ne mrmljajte među sobom!"},{"v":44,"t":"Nitko ne može doći k meni ako ga ne povuče Otac koji me posla; i ja ću ga uskrisiti u posljednji dan."},{"v":45,"t":"Pisano je u Prorocima: Svi će biti učenici Božji. Tko god čuje od Oca i pouči se, dolazi k meni."},{"v":46,"t":"Ne da bi tko vidio Oca, doli onaj koji je kod Boga; on je vidio Oca."},{"v":47,"t":"Zaista, zaista, kažem vam: tko vjeruje, ima život vječni."},{"v":48,"t":"Ja sam kruh života."},{"v":49,"t":"Očevi vaši jedoše u pustinji manu i pomriješe."},{"v":50,"t":"Ovo je kruh koji silazi s neba: da tko od njega jede, ne umre."},{"v":51,"t":"Ja sam kruh živi koji je s neba sišao. Tko bude jeo od ovoga kruha, živjet će uvijeke. Kruh koji ću ja dati tijelo je moje - za život svijeta.”"},{"v":52,"t":"Židovi se nato među sobom prepirahu: “Kako nam ovaj može dati tijelo svoje za jelo?”"},{"v":53,"t":"Reče im stoga Isus: “Zaista, zaista, kažem vam: ako ne jedete tijela Sina Čovječjega i ne pijete krvi njegove, nemate života u sebi!"},{"v":54,"t":"Tko blaguje tijelo moje i pije krv moju, ima život vječni; i ja ću ga uskrisiti u posljednji dan."},{"v":55,"t":"Tijelo je moje jelo istinsko, krv je moja piće istinsko."},{"v":56,"t":"Tko jede moje tijelo i pije moju krv, u meni ostaje i ja u njemu."},{"v":57,"t":"Kao što je mene poslao živi Otac i ja živim po Ocu, tako i onaj koji mene blaguje živjet će po meni."},{"v":58,"t":"Ovo je kruh koji je s neba sišao, ne kao onaj koji jedoše očevi i pomriješe. Tko jede ovaj kruh, živjet će uvijeke.”"},{"v":59,"t":"To reče Isus naučavajući u sinagogi u Kafarnaumu."},{"v":60,"t":"Mnogi od njegovih učenika čuvši to rekoše: “Tvrda je to besjeda! Tko je može slušati?”"},{"v":61,"t":"A Isus znajući sam od sebe da njegovi učenici zbog toga mrmljaju, reče im: “Zar vas to sablažnjava?"},{"v":62,"t":"A što ako vidite Sina Čovječjega kako uzlazi onamo gdje je prije bio?”"},{"v":63,"t":"“Duh je onaj koji oživljuje, tijelo ne koristi ništa. Riječi koje sam vam govorio duh su i život su.”"},{"v":64,"t":"“A ipak, ima ih među vama koji ne vjeruju.” Jer znao je Isus od početka koji su oni što ne vjeruju i tko je onaj koji će ga izdati."},{"v":65,"t":"I doda: “Zato sam vam i rekao da nitko ne može doći k meni ako mu nije dano od Oca.”"},{"v":66,"t":"Otada mnogi učenici odstupiše, više nisu išli s njime."},{"v":67,"t":"Reče stoga Isus dvanaestorici: “Da možda i vi ne kanite otići?”"},{"v":68,"t":"Odgovori mu Šimun Petar: “Gospodine, kome da idemo? Ti imaš riječi života vječnoga!"},{"v":69,"t":"I mi vjerujemo i znamo: ti si Svetac Božji.”"},{"v":70,"t":"Odgovori im Isus: “Nisam li ja vas dvanaestoricu izabrao? A ipak, jedan je od vas đavao.”"},{"v":71,"t":"Govoraše to o Judi, sinu Šimuna Iškariotskoga, jednom od dvanaestorice, jer on ga je imao izdati."}]},"7":{"fa":[{"v":1,"t":"و بعد از آن عیسی در جلیل می‌گشت زیرانمی خواست در یهودیه راه رود چونکه یهودیان قصد قتل او می‌داشتند."},{"v":2,"t":"و عید یهود که عید خیمه‌ها باشد نزدیک بود."},{"v":3,"t":"پس برادرانش بدو گفتند: «از اینجا روانه شده، به یهودیه برو تاشاگردانت نیز آن اعمالی را که تو می‌کنی ببینند،"},{"v":4,"t":"زیرا هر‌که می‌خواهد آشکار شود در پنهانی کارنمی کند. پس اگر این کارها را می‌کنی خود را به جهان بنما.»"},{"v":5,"t":"زیرا که برادرانش نیز به او ایمان نیاورده بودند."},{"v":6,"t":"آنگاه عیسی بدیشان گفت: «وقت من هنوز نرسیده، اما وقت شما همیشه حاضراست."},{"v":7,"t":"جهان نمی تواند شما را دشمن دارد ولیکن مرا دشمن می‌دارد زیرا که من بر آن شهادت می‌دهم که اعمالش بد است."},{"v":8,"t":"شما برای این عیدبروید. من حال به این عید نمی آیم زیرا که وقت من هنوز تمام نشده است.»"},{"v":9,"t":"چون این را بدیشان گفت، در جلیل توقف نمود."},{"v":10,"t":"لیکن چون برادرانش برای عید رفته بودند، او نیز آمد، نه آشکار بلکه در خفا."},{"v":11,"t":"اما یهودیان در عید او را جستجو نموده، می‌گفتند که او کجااست."},{"v":12,"t":"و در میان مردم درباره او همهمه بسیاربود. بعضی می‌گفتند که مردی نیکو است ودیگران می‌گفتند نی بلکه گمراه‌کننده قوم است."},{"v":13,"t":"و لیکن بسبب ترس از یهود، هیچ‌کس درباره اوظاهر حرف نمی زد."},{"v":14,"t":"و چون نصف عید گذشته بود، عیسی به هیکل آمده، تعلیم می‌داد."},{"v":15,"t":"و یهودیان تعجب نموده، گفتند: «این شخص هرگز تعلیم نیافته، چگونه کتب را می‌داند؟»"},{"v":16,"t":"عیسی در جواب ایشان گفت: «تعلیم من از من نیست، بلکه ازفرستنده من."},{"v":17,"t":"اگر کسی بخواهد اراده او را به عمل آرد، درباره تعلیم خواهد دانست که از خدااست یا آنکه من از خود سخن می‌رانم."},{"v":18,"t":"هر‌که ازخود سخن گوید، جلال خود را طالب بود و اماهر‌که طالب جلال فرستنده خود باشد، او صادق است و در او ناراستی نیست."},{"v":19,"t":"آیا موسی تورات را به شما نداده است؟ و حال آنکه کسی از شما نیست که به تورات عمل کند. از برای چه می‌خواهید مرا به قتل رسانید؟»"},{"v":20,"t":"آنگاه همه درجواب گفتند: «تو دیو داری. که اراده دارد تو رابکشد؟»"},{"v":21,"t":"عیسی در جواب ایشان گفت: «یک عمل نمودم وهمه شما از آن متعجب شدید."},{"v":22,"t":"موسی ختنه را به شما داد نه آنکه از موسی باشد بلکه از اجداد و در روز سبت مردم را ختنه می‌کنید."},{"v":23,"t":"پس اگر کسی در روز سبت مختون شود تا شریعت موسی شکسته نشود، چرا بر من خشم می‌آورید از آن سبب که در روز سبت شخصی را شفای کامل دادم؟"},{"v":24,"t":"بحسب ظاهرداوری مکنید بلکه به راستی داوری نمایید.»"},{"v":25,"t":"پس بعضی از اهل اورشلیم گفتند: «آیا این آن نیست که قصد قتل او دارند؟"},{"v":26,"t":"و اینک آشکارا حرف می‌زند و بدو هیچ نمی گویند. آیاروسا یقین می‌دانند که او در حقیقت مسیح است؟"},{"v":27,"t":"لیکن این شخص را می‌دانیم از کجا است، امامسیح چون آید هیچ‌کس نمی شناسد که از کجااست.»"},{"v":28,"t":"و عیسی چون در هیکل تعلیم می‌داد، ندا کرده، گفت: «مرا می‌شناسید و نیز می‌دانید ازکجا هستم و از خود نیامده‌ام بلکه فرستنده من حق است که شما او را نمی شناسید."},{"v":29,"t":"اما من اورا می‌شناسم زیرا که از او هستم و او مرا فرستاده است.»"},{"v":30,"t":"آنگاه خواستند او را گرفتار کنند ولیکن کسی بر او دست نینداخت زیرا که ساعت او هنوزنرسیده بود."},{"v":31,"t":"آنگاه بسیاری از آن گروه بدوایمان آوردند و گفتند: «آیا چون مسیح آید، معجزات بیشتر از اینها که این شخص می‌نماید، خواهد نمود؟»"},{"v":32,"t":"چون فریسیان شنیدند که خلق درباره اواین همهمه می‌کنند، فریسیان و روسای کهنه خادمان فرستادند تا او را بگیرند."},{"v":33,"t":"آنگاه عیسی گفت: «اندک زمانی دیگر با شما هستم، بعد نزدفرستنده خود می‌روم."},{"v":34,"t":"و مرا طلب خواهید کردو نخواهید یافت و آنجایی که من هستم شمانمی توانید آمد.»"},{"v":35,"t":"پس یهودیان با یکدیگرگفتند: «او کجا می‌خواهد برود که ما او رانمی یابیم؟ آیا اراده دارد به سوی پراکندگان یونانیان رود و یونانیان را تعلیم دهد؟"},{"v":36,"t":"این چه کلامی است که گفت مرا طلب خواهید کرد ونخواهید یافت و جایی که من هستم شمانمی توانید آمد؟»"},{"v":37,"t":"و در روز آخر که روز بزرگ عید بود، عیسی ایستاده، ندا کرد و گفت: «هر‌که تشنه باشدنزد من آید و بنوشد."},{"v":38,"t":"کسی‌که به من ایمان آورد، چنانکه کتاب می‌گوید، از بطن او نهرهای آب زنده جاری خواهد شد.»"},{"v":39,"t":"اما این را گفت درباره روح که هر‌که به او ایمان آرد او را خواهدیافت زیرا که روح‌القدس هنوز عطا نشده بود، چونکه عیسی تا به حال جلال نیافته بود."},{"v":40,"t":"آنگاه بسیاری از آن گروه، چون این کلام راشنیدند، گفتند: «در حقیقت این شخص همان نبی است.»"},{"v":41,"t":"و بعضی گفتند: «او مسیح است.» وبعضی گفتند: «مگر مسیح از جلیل خواهد آمد؟"},{"v":42,"t":"آیا کتاب نگفته است که از نسل داود و ازبیت لحم، دهی که داود در آن بود، مسیح ظاهر خواهد شد؟»"},{"v":43,"t":"پس درباره او در میان مردم اختلاف افتاد."},{"v":44,"t":"و بعضی از ایشان خواستند او رابگیرند و لکن هیچ‌کس بر او دست نینداخت."},{"v":45,"t":"پس خادمان نزد روسای کهنه و فریسیان آمدند. آنها بدیشان گفتند: «برای چه او رانیاوردید؟»"},{"v":46,"t":"خادمان در جواب گفتند: «هرگزکسی مثل این شخص سخن نگفته است!»"},{"v":47,"t":"آنگاه فریسیان در جواب ایشان گفتند: «آیاشما نیز گمراه شده‌اید؟"},{"v":48,"t":"مگر کسی از سرداران یا از فریسیان به او ایمان آورده است؟"},{"v":49,"t":"ولیکن این گروه که شریعت را نمی دانند، ملعون می‌باشند.»"},{"v":50,"t":"نیقودیموس، آنکه در شب نزد اوآمده و یکی از ایشان بود بدیشان گفت:"},{"v":51,"t":"«آیاشریعت ما بر کسی فتوی می‌دهد، جز آنکه اول سخن او را بشنوند و کار او را دریافت کنند؟»"},{"v":52,"t":"ایشان در جواب وی گفتند: «مگر تو نیزجلیلی هستی؟ تفحص کن و ببین زیرا که هیچ نبی از جلیل برنخاسته است.» پس هر یک به خانه خود رفتند."}],"en":[{"v":1,"t":"After these things, Jesus was walking in Galilee, for he wouldn’t walk in Judea, because the Jews sought to kill him."},{"v":2,"t":"Now the feast of the Jews, the Feast of Booths, was at hand."},{"v":3,"t":"His brothers therefore said to him, “Depart from here and go into Judea, that your disciples also may see your works which you do."},{"v":4,"t":"For no one does anything in secret while he seeks to be known openly. If you do these things, reveal yourself to the world.”"},{"v":5,"t":"For even his brothers didn’t believe in him."},{"v":6,"t":"Jesus therefore said to them, “My time has not yet come, but your time is always ready."},{"v":7,"t":"The world can’t hate you, but it hates me, because I testify about it, that its works are evil."},{"v":8,"t":"You go up to the feast. I am not yet going up to this feast, because my time is not yet fulfilled.”"},{"v":9,"t":"Having said these things to them, he stayed in Galilee."},{"v":10,"t":"But when his brothers had gone up to the feast, then he also went up, not publicly, but as it were in secret."},{"v":11,"t":"The Jews therefore sought him at the feast, and said, “Where is he?”"},{"v":12,"t":"There was much murmuring among the multitudes concerning him. Some said, “He is a good man.” Others said, “Not so, but he leads the multitude astray.”"},{"v":13,"t":"Yet no one spoke openly of him for fear of the Jews."},{"v":14,"t":"But when it was now the middle of the feast, Jesus went up into the temple and taught."},{"v":15,"t":"The Jews therefore marveled, saying, “How does this man know letters, having never been educated?”"},{"v":16,"t":"Jesus therefore answered them, “My teaching is not mine, but his who sent me."},{"v":17,"t":"If anyone desires to do his will, he will know about the teaching, whether it is from God or if I am speaking from myself."},{"v":18,"t":"He who speaks from himself seeks his own glory, but he who seeks the glory of him who sent him is true, and no unrighteousness is in him."},{"v":19,"t":"Didn’t Moses give you the law, and yet none of you keeps the law? Why do you seek to kill me?”"},{"v":20,"t":"The multitude answered, “You have a demon! Who seeks to kill you?”"},{"v":21,"t":"Jesus answered them, “I did one work and you all marvel because of it."},{"v":22,"t":"Moses has given you circumcision (not that it is of Moses, but of the fathers), and on the Sabbath you circumcise a boy."},{"v":23,"t":"If a boy receives circumcision on the Sabbath, that the law of Moses may not be broken, are you angry with me because I made a man completely healthy on the Sabbath?"},{"v":24,"t":"Don’t judge according to appearance, but judge righteous judgment.”"},{"v":25,"t":"Therefore some of them of Jerusalem said, “Isn’t this he whom they seek to kill?"},{"v":26,"t":"Behold, he speaks openly, and they say nothing to him. Can it be that the rulers indeed know that this is truly the Christ?"},{"v":27,"t":"However, we know where this man comes from, but when the Christ comes, no one will know where he comes from.”"},{"v":28,"t":"Jesus therefore cried out in the temple, teaching and saying, “You both know me, and know where I am from. I have not come of myself, but he who sent me is true, whom you don’t know."},{"v":29,"t":"I know him, because I am from him, and he sent me.”"},{"v":30,"t":"They sought therefore to take him; but no one laid a hand on him, because his hour had not yet come."},{"v":31,"t":"But of the multitude, many believed in him. They said, “When the Christ comes, he won’t do more signs than those which this man has done, will he?”"},{"v":32,"t":"The Pharisees heard the multitude murmuring these things concerning him, and the chief priests and the Pharisees sent officers to arrest him."},{"v":33,"t":"Then Jesus said, “I will be with you a little while longer, then I go to him who sent me."},{"v":34,"t":"You will seek me and won’t find me. You can’t come where I am.”"},{"v":35,"t":"The Jews therefore said among themselves, “Where will this man go that we won’t find him? Will he go to the Dispersion among the Greeks and teach the Greeks?"},{"v":36,"t":"What is this word that he said, ‘You will seek me, and won’t find me;’ and ‘Where I am, you can’t come’?”"},{"v":37,"t":"Now on the last and greatest day of the feast, Jesus stood and cried out, “If anyone is thirsty, let him come to me and drink!"},{"v":38,"t":"He who believes in me, as the Scripture has said, from within him will flow rivers of living water.”"},{"v":39,"t":"But he said this about the Spirit, which those believing in him were to receive. For the Holy Spirit was not yet given, because Jesus wasn’t yet glorified."},{"v":40,"t":"Many of the multitude therefore, when they heard these words, said, “This is truly the prophet.”"},{"v":41,"t":"Others said, “This is the Christ.” But some said, “What, does the Christ come out of Galilee?"},{"v":42,"t":"Hasn’t the Scripture said that the Christ comes of the offspring of David, and from Bethlehem, the village where David was?”"},{"v":43,"t":"So a division arose in the multitude because of him."},{"v":44,"t":"Some of them would have arrested him, but no one laid hands on him."},{"v":45,"t":"The officers therefore came to the chief priests and Pharisees; and they said to them, “Why didn’t you bring him?”"},{"v":46,"t":"The officers answered, “No man ever spoke like this man!”"},{"v":47,"t":"The Pharisees therefore answered them, “You aren’t also led astray, are you?"},{"v":48,"t":"Have any of the rulers or any of the Pharisees believed in him?"},{"v":49,"t":"But this multitude that doesn’t know the law is cursed.”"},{"v":50,"t":"Nicodemus (he who came to him by night, being one of them) said to them,"},{"v":51,"t":"“Does our law judge a man unless it first hears from him personally and knows what he does?”"},{"v":52,"t":"They answered him, “Are you also from Galilee? Search and see that no prophet has arisen out of Galilee.”"},{"v":53,"t":"Everyone went to his own house,"}],"hr":[{"v":1,"t":"Nakon toga Isus je obilazio po Galileji; nije htio u Judeju jer su Židovi tražili da ga ubiju."},{"v":2,"t":"Bijaše blizu židovski Blagdan sjenica."},{"v":3,"t":"Rekoše mu stoga njegova braća: “Otiđi odavle i pođi u Judeju da i tvoji učenici vide djela što činiš."},{"v":4,"t":"Ta tko želi biti javno poznat, ne čini ništa u tajnosti. Ako već činiš sve to, očituj se svijetu.”"},{"v":5,"t":"Jer ni braća njegova nisu vjerovala u njega."},{"v":6,"t":"Reče im nato Isus: “Moje vrijeme još nije došlo, a za vas je vrijeme svagda pogodno."},{"v":7,"t":"Vas svijet ne može mrziti, ali mene mrzi jer ja svjedočim protiv njega: da su mu djela opaka."},{"v":8,"t":"Vi samo uziđite na blagdan. Ja još ne uzlazim na ovaj blagdan jer moje se vrijeme još nije ispunilo.”"},{"v":9,"t":"To im reče i ostade u Galileji."},{"v":10,"t":"Ali pošto njegova braća uziđoše na blagdan, uziđe i on, ne javno, nego potajno."},{"v":11,"t":"A Židovi su ga tražili o blagdanu pitajući : “Gdje je onaj?”"},{"v":12,"t":"I među mnoštvom o njemu se mnogo šaptalo. Jedni govorahu: “Dobar je!” Drugi pak: “Ne, nego zavodi narod.”"},{"v":13,"t":"Ipak nitko nije otvoreno govorio o njemu zbog straha od Židova."},{"v":14,"t":"Usred blagdana uziđe Isus u Hram i stade naučavati."},{"v":15,"t":"Židovi se u čudu pitahu: “Kako ovaj znade Pisma, a nije učio?”"},{"v":16,"t":"Nato im Isus odvrati: “Moj nauk nije moj, nego onoga koji me posla."},{"v":17,"t":"Ako tko hoće vršiti volju njegovu, prepoznat će da li je taj nauk od Boga ili ja sam od sebe govorim."},{"v":18,"t":"Tko sam od sebe govori, svoju slavu traži, a tko traži slavu onoga koji ga posla, taj je istinit i nema u njemu nepravednosti."},{"v":19,"t":"Nije li vam Mojsije dao Zakon? Pa ipak nitko od vas ne vrši Zakona.” “Zašto tražite da me ubijete?”"},{"v":20,"t":"Odgovori mnoštvo: “Zloduha imaš! Tko traži da te ubije?”"},{"v":21,"t":"Uzvrati im Isus: “Jedno djelo učinih i svi se čudite."},{"v":22,"t":"Mojsije vam dade obrezanje - ne, ono i nije od Mojsija, nego od otaca - i vi u subotu obrezujete čovjeka."},{"v":23,"t":"Ako čovjek može primiti obrezanje u subotu da se ne prekrši Mojsijev zakon, zašto se ljutite na mene što sam svega čovjeka ozdravio u subotu?"},{"v":24,"t":"Ne sudite po vanjštini, nego sudite sudom pravednim!”"},{"v":25,"t":"Rekoše tada neki Jeruzalemci: “Nije li to onaj koga traže da ga ubiju?"},{"v":26,"t":"A evo, posve otvoreno govori i ništa mu ne kažu. Da nisu možda i glavari doista upoznali da je on Krist?"},{"v":27,"t":"Ali za njega znamo odakle je, a kad Krist dođe, nitko neće znati odakle je!”"},{"v":28,"t":"Nato Isus, koji je učio u Hramu, povika: “Da! Poznajete me i znate odakle sam! A ipak ja nisam došao sam od sebe: postoji jedan istiniti koji me posla. Njega vi ne znate."},{"v":29,"t":"Ja ga znadem jer sam od njega i on me poslao.”"},{"v":30,"t":"Židovi su otad vrebali da ga uhvate. Ipak nitko ne stavi na nj ruke jer još nije bio došao njegov čas."},{"v":31,"t":"A mnogi iz mnoštva povjerovaše u nj te govorahu: “Zar će Krist, kada dođe, činiti više znamenja nego što ih ovaj učini?”"},{"v":32,"t":"Dočuli farizeji da se to u mnoštvu o njemu šapće. Stoga glavari svećenički i farizeji poslaše stražare da ga uhvate."},{"v":33,"t":"Tada Isus reče: “Još sam malo vremena s vama i odlazim onomu koji me posla."},{"v":34,"t":"Tražit ćete me i nećete me naći; gdje sam ja, vi ne možete doći.”"},{"v":35,"t":"Rekoše nato Židovi među sobom: “Kamo to ovaj kani da ga mi nećemo naći? Da ne kani poći raseljenima među Grcima i naučavati Grke?"},{"v":36,"t":"Što li znači besjeda koju reče: 'Tražit ćete me i nećete me naći; gdje sam ja, vi ne možete doći'?”"},{"v":37,"t":"U posljednji, veliki dan blagdana Isus stade i povika: “Ako je tko žedan, neka dođe k meni! Neka pije"},{"v":38,"t":"koji vjeruje u mene! Kao što reče Pismo: 'Rijeke će žive vode poteći iz njegove utrobe!'”"},{"v":39,"t":"To reče o Duhu kojega su imali primiti oni što vjeruju u njega. Tada doista ne bijaše još došao Duh jer Isus nije bio proslavljen."},{"v":40,"t":"Kad su neki iz naroda čuli te riječi, govorahu: “Ovo je uistinu Prorok.”"},{"v":41,"t":"Drugi govorahu: “Ovo je Krist.” A bilo ih je i koji su pitali: “Pa zar Krist dolazi iz Galileje?"},{"v":42,"t":"Ne kaže li Pismo da Krist dolazi iz potomstva Davidova, i to iz Betlehema, mjesta gdje bijaše David?”"},{"v":43,"t":"Tako je u narodu nastala podvojenost zbog njega."},{"v":44,"t":"Neki ga čak htjedoše uhvatiti, ali nitko ne stavi na nj ruke."},{"v":45,"t":"Dođoše dakle stražari glavarima svećeničkim i farizejima, a ovi im rekoše: “Zašto ga ne dovedoste?”"},{"v":46,"t":"Stražari odgovore: “Nikada nitko nije ovako govorio.”"},{"v":47,"t":"Nato će im farizeji: “Zar ste se i vi dali zavesti?"},{"v":48,"t":"Je li itko od glavara ili farizeja povjerovao u njega?"},{"v":49,"t":"Ali ta svjetina koja ne pozna Zakona - to je prokleto!”"},{"v":50,"t":"Kaže im Nikodem - onaj koji ono prije dođe k Isusu, a bijaše jedan od njih:"},{"v":51,"t":"“Zar naš Zakon sudi čovjeku ako ga prije ne sasluša i ne dozna što čini?”"},{"v":52,"t":"Odgovoriše mu: “Da nisi i ti iz Galileje? Istraži pa ćeš vidjeti da iz Galileje ne ustaje prorok.”"},{"v":53,"t":"I otiđoše svaki svojoj kući."}]},"8":{"fa":[{"v":1,"t":"اما عیسی به کوه زیتون رفت."},{"v":2,"t":"و بامدادان باز به هیکل آمد و چون جمیع قوم نزد اوآمدند نشسته، ایشان را تعلیم می‌داد."},{"v":3,"t":"که ناگاه کاتبان و فریسیان زنی را که در زنا گرفته شده بود، پیش او آوردند و او را در میان برپا داشته،"},{"v":4,"t":"بدوگفتند: «ای استاد، این زن در عین عمل زنا گرفته شد؛"},{"v":5,"t":"و موسی در تورات به ما حکم کرده است که چنین زنان سنگسار شوند. اما تو چه می‌گویی؟»"},{"v":6,"t":"و این را از روی امتحان بدو گفتند تا ادعایی بر او پیدا کنند. اما عیسی سر به زیرافکنده، به انگشت خود بر روی زمین می‌نوشت."},{"v":7,"t":"و چون در سوال کردن الحاح می‌نمودند، راست شده، بدیشان گفت: «هر‌که از شما گناه ندارد اول بر او سنگ اندازد.»"},{"v":8,"t":"و باز سر به زیر افکنده، برزمین می‌نوشت."},{"v":9,"t":"پس چون شنیدند، از ضمیرخود ملزم شده، از مشایخ شروع کرده تا به آخر، یک یک بیرون رفتند و عیسی تنها باقی ماند با آن زن که در میان ایستاده بود."},{"v":10,"t":"پس عیسی چون راست شد و غیر از زن کسی را ندید، بدو گفت: «ای زن آن مدعیان تو کجا شدند؟ آیا هیچ‌کس برتو فتوا نداد؟»"},{"v":11,"t":"گفت: «هیچ‌کس‌ای آقا.» عیسی گفت: «من هم بر تو فتوا نمی دهم. برو دیگر گناه مکن.»"},{"v":12,"t":"پس عیسی باز بدیشان خطاب کرده، گفت: «من نور عالم هستم. کسی‌که مرا متابعت کند، درظلمت سالک نشود بلکه نور حیات را یابد.»"},{"v":13,"t":"آنگاه فریسیان بدو گفتند: «تو بر خود شهادت می‌دهی، پس شهادت تو راست نیست.»"},{"v":14,"t":"عیسی در جواب ایشان گفت: «هرچند من برخود شهادت می‌دهم، شهادت من راست است زیرا که می‌دانم از کجا آمده‌ام و به کجا خواهم رفت، لیکن شما نمی دانید از کجا آمده‌ام و به کجامی روم."},{"v":15,"t":"شما بحسب جسم حکم می‌کنید امامن بر هیچ‌کس حکم نمی کنم."},{"v":16,"t":"و اگر من حکم دهم، حکم من راست است، از آنرو که تنها نیستم بلکه من و پدری که مرا فرستاد."},{"v":17,"t":"و نیز درشریعت شما مکتوب است که شهادت دو کس حق است."},{"v":18,"t":"من بر خود شهادت می‌دهم و پدری که مرا فرستاد نیز برای من شهادت می‌دهد.»"},{"v":19,"t":"بدو گفتند: «پدر تو کجا است؟» عیسی جواب داد که «نه مرا می‌شناسید و نه پدر مرا. هرگاه مرامی شناختید پدر مرا نیز می‌شناختید.»"},{"v":20,"t":"و این کلام را عیسی در بیت‌المال گفت، وقتی که درهیکل تعلیم می‌داد و هیچ‌کس او را نگرفت بجهت آنکه ساعت او هنوز نرسیده بود."},{"v":21,"t":"باز عیسی بدیشان گفت: «من می‌روم و مراطلب خواهید کرد و در گناهان خود خواهید مردو جایی که من می‌روم شما نمی توانید آمد.»"},{"v":22,"t":"یهودیان گفتند: «آیا اراده قتل خود دارد که می‌گوید به‌جایی خواهم رفت که شما نمی توانیدآمد؟»"},{"v":23,"t":"ایشان را گفت: «شما از پایین می‌باشیداما من از بالا. شما از این جهان هستید، لیکن من ازاین جهان نیستم."},{"v":24,"t":"از این جهت به شما گفتم که در گناهان خود خواهید مرد، زیرا اگر باور نکنیدکه من هستم در گناهان خود خواهید مرد.»"},{"v":25,"t":"بدوگفتند: «تو کیستی؟» عیسی بدیشان گفت: «همانم که از اول نیز به شما گفتم."},{"v":26,"t":"من چیزهای بسیاردارم که درباره شما بگویم و حکم کنم؛ لکن آنکه مرا فرستاد حق است و من آنچه از او شنیده‌ام به جهان می‌گویم.»"},{"v":27,"t":"ایشان نفهمیدند که بدیشان درباره پدر سخن می‌گوید."},{"v":28,"t":"عیسی بدیشان گفت: «وقتی که پسر انسان را بلند کردید، آن وقت خواهید دانست که من هستم و از خود کاری نمی کنم بلکه به آنچه پدرم مرا تعلیم داد تکلم می‌کنم."},{"v":29,"t":"و او که مرا فرستاد، با من است و پدر مرا تنها نگذارده است زیرا که من همیشه کارهای پسندیده او را به‌جا می‌آورم.»"},{"v":30,"t":"چون این را گفت، بسیاری بدو ایمان آوردند."},{"v":31,"t":"پس عیسی به یهودیانی که بدو ایمان آوردند گفت: «اگر شما در کلام من بمانیدفی الحقیقه شاگرد من خواهید شد،"},{"v":32,"t":"و حق راخواهید شناخت و حق شما را آزاد خواهد کرد.»"},{"v":33,"t":"بدو جواب دادند که «اولاد ابراهیم می‌باشیم وهرگز هیچ‌کس را غلام نبوده‌ایم. پس چگونه تومی گویی که آزاد خواهید شد؟»"},{"v":34,"t":"عیسی درجواب ایشان گفت: «آمین آمین به شما می‌گویم هر‌که گناه می‌کند غلام گناه است."},{"v":35,"t":"و غلام همیشه در خانه نمی ماند، اما پسر همیشه می‌ماند."},{"v":36,"t":"پس اگر پسر شما را آزاد کند، در حقیقت آزادخواهید بود."},{"v":37,"t":"می‌دانم که اولاد ابراهیم هستید، لیکن می‌خواهید مرا بکشید زیرا کلام من در شماجای ندارد."},{"v":38,"t":"من آنچه نزد پدر خود دیده‌ام می‌گویم و شما آنچه نزد پدر خود دیده ایدمی کنید.»"},{"v":39,"t":"در جواب او گفتند که «پدر ماابراهیم است.» عیسی بدیشان گفت: «اگر اولادابراهیم می‌بودید، اعمال ابراهیم را به‌جامی آوردید."},{"v":40,"t":"ولیکن الان می‌خواهید مرا بکشیدو من شخصی هستم که با شما به راستی که از خداشنیده‌ام تکلم می‌کنم. ابراهیم چنین نکرد."},{"v":41,"t":"شمااعمال پدر خود را به‌جا می‌آورید.»"},{"v":42,"t":"عیسی به ایشان گفت: «اگر خدا پدر شما می‌بود، مرا دوست می داشتید، زیرا که من از جانب خدا صادر شده وآمده‌ام، زیرا که من از پیش خود نیامده‌ام بلکه اومرا فرستاده است."},{"v":43,"t":"برای چه سخن مرانمی فهمید؟ از آنجهت که کلام مرا نمی توانیدبشنوید."},{"v":44,"t":"شما از پدر خود ابلیس می‌باشید وخواهشهای پدر خود را می‌خواهید به عمل آرید. او از اول قاتل بود و در راستی ثابت نمی باشد، از آنجهت که در او راستی نیست. هرگاه به دروغ سخن می‌گوید، از ذات خودمی گوید زیرا دروغگو و پدر دروغگویان است."},{"v":45,"t":"و اما من از این سبب که راست می‌گویم، مراباور نمی کنید."},{"v":46,"t":"کیست از شما که مرا به گناه ملزم سازد؟ پس اگر راست می‌گویم، چرا مرا باورنمی کنید؟"},{"v":47,"t":"کسی‌که از خدا است، کلام خدا رامی شنود و از این سبب شما نمی شنوید که از خدانیستید.»"},{"v":48,"t":"پس یهودیان در جواب او گفتند: «آیا ماخوب نگفتیم که تو سامری هستی و دیو داری؟»"},{"v":49,"t":"عیسی جواب داد که «من دیو ندارم، لکن پدرخود را حرمت می‌دارم و شما مرا بی‌حرمت می‌سازید."},{"v":50,"t":"من جلال خود را طالب نیستم، کسی هست که می‌طلبد و داوری می‌کند."},{"v":51,"t":"آمین آمین به شما می‌گویم، اگر کسی کلام مرا حفظکند، موت را تا به ابد نخواهد دید.»"},{"v":52,"t":"پس یهودیان بدو گفتند: «الان دانستیم که دیو داری! ابراهیم و انبیا مردند و تو می‌گویی اگر کسی کلام مرا حفظ کند، موت را تا به ابد نخواهد چشید"},{"v":53,"t":"آیا تو از پدر ما ابراهیم که مرد و انبیایی که مردند بزرگتر هستی؟ خود را که می‌دانی؟»"},{"v":54,"t":"عیسی در جواب داد: «اگر خود را جلال دهم، جلال من چیزی نباشد. پدر من آن است که مرا جلال می‌بخشد، آنکه شما می‌گویید خدای ما است."},{"v":55,"t":"و او را نمی شناسید، اما من او رامی شناسم و اگر گویم او را نمی شناسم مثل شمادروغگو می‌باشم. لیکن او را می‌شناسم و قول اورا نگاه می‌دارم."},{"v":56,"t":"پدر شما ابراهیم شادی کرد براینکه روز مرا ببیند و دید و شادمان گردید.»"},{"v":57,"t":"یهودیان بدو گفتند: «هنوز پنجاه سال نداری وابراهیم را دیده‌ای؟»"},{"v":58,"t":"عیسی بدیشان گفت: «آمین آمین به شما می‌گویم که پیش از آنکه ابراهیم پیدا شود من هستم.»"},{"v":59,"t":"آنگاه سنگهابرداشتند تا او را سنگسار کنند. اما عیسی خود رامخفی ساخت و از میان گذشته، از هیکل بیرون شد و همچنین برفت."}],"en":[{"v":1,"t":"but Jesus went to the Mount of Olives."},{"v":2,"t":"Now very early in the morning, he came again into the temple, and all the people came to him. He sat down and taught them."},{"v":3,"t":"The scribes and the Pharisees brought a woman taken in adultery. Having set her in the middle,"},{"v":4,"t":"they told him, “Teacher, we found this woman in adultery, in the very act."},{"v":5,"t":"Now in our law, Moses commanded us to stone such women. What then do you say about her?”"},{"v":6,"t":"They said this testing him, that they might have something to accuse him of. But Jesus stooped down and wrote on the ground with his finger."},{"v":7,"t":"But when they continued asking him, he looked up and said to them, “He who is without sin among you, let him throw the first stone at her.”"},{"v":8,"t":"Again he stooped down and wrote on the ground with his finger."},{"v":9,"t":"They, when they heard it, being convicted by their conscience, went out one by one, beginning from the oldest, even to the last. Jesus was left alone with the woman where she was, in the middle."},{"v":10,"t":"Jesus, standing up, saw her and said, “Woman, where are your accusers? Did no one condemn you?”"},{"v":11,"t":"She said, “No one, Lord.” Jesus said, “Neither do I condemn you. Go your way. From now on, sin no more.”"},{"v":12,"t":"Again, therefore, Jesus spoke to them, saying, “I am the light of the world. He who follows me will not walk in the darkness, but will have the light of life.”"},{"v":13,"t":"The Pharisees therefore said to him, “You testify about yourself. Your testimony is not valid.”"},{"v":14,"t":"Jesus answered them, “Even if I testify about myself, my testimony is true, for I know where I came from, and where I am going; but you don’t know where I came from, or where I am going."},{"v":15,"t":"You judge according to the flesh. I judge no one."},{"v":16,"t":"Even if I do judge, my judgment is true, for I am not alone, but I am with the Father who sent me."},{"v":17,"t":"It’s also written in your law that the testimony of two people is valid."},{"v":18,"t":"I am one who testifies about myself, and the Father who sent me testifies about me.”"},{"v":19,"t":"They said therefore to him, “Where is your Father?” Jesus answered, “You know neither me nor my Father. If you knew me, you would know my Father also.”"},{"v":20,"t":"Jesus spoke these words in the treasury, as he taught in the temple. Yet no one arrested him, because his hour had not yet come."},{"v":21,"t":"Jesus said therefore again to them, “I am going away, and you will seek me, and you will die in your sins. Where I go, you can’t come.”"},{"v":22,"t":"The Jews therefore said, “Will he kill himself, because he says, ‘Where I am going, you can’t come’?”"},{"v":23,"t":"He said to them, “You are from beneath. I am from above. You are of this world. I am not of this world."},{"v":24,"t":"I said therefore to you that you will die in your sins; for unless you believe that I am he, you will die in your sins.”"},{"v":25,"t":"They said therefore to him, “Who are you?” Jesus said to them, “Just what I have been saying to you from the beginning."},{"v":26,"t":"I have many things to speak and to judge concerning you. However, he who sent me is true; and the things which I heard from him, these I say to the world.”"},{"v":27,"t":"They didn’t understand that he spoke to them about the Father."},{"v":28,"t":"Jesus therefore said to them, “When you have lifted up the Son of Man, then you will know that I am he, and I do nothing of myself, but as my Father taught me, I say these things."},{"v":29,"t":"He who sent me is with me. The Father hasn’t left me alone, for I always do the things that are pleasing to him.”"},{"v":30,"t":"As he spoke these things, many believed in him."},{"v":31,"t":"Jesus therefore said to those Jews who had believed him, “If you remain in my word, then you are truly my disciples."},{"v":32,"t":"You will know the truth, and the truth will make you free.”"},{"v":33,"t":"They answered him, “We are Abraham’s offspring, and have never been in bondage to anyone. How do you say, ‘You will be made free’?”"},{"v":34,"t":"Jesus answered them, “Most certainly I tell you, everyone who commits sin is the bondservant of sin."},{"v":35,"t":"A bondservant doesn’t live in the house forever. A son remains forever."},{"v":36,"t":"If therefore the Son makes you free, you will be free indeed."},{"v":37,"t":"I know that you are Abraham’s offspring, yet you seek to kill me, because my word finds no place in you."},{"v":38,"t":"I say the things which I have seen with my Father; and you also do the things which you have seen with your father.”"},{"v":39,"t":"They answered him, “Our father is Abraham.” Jesus said to them, “If you were Abraham’s children, you would do the works of Abraham."},{"v":40,"t":"But now you seek to kill me, a man who has told you the truth which I heard from God. Abraham didn’t do this."},{"v":41,"t":"You do the works of your father.” They said to him, “We were not born of sexual immorality. We have one Father, God.”"},{"v":42,"t":"Therefore Jesus said to them, “If God were your father, you would love me, for I came out and have come from God. For I haven’t come of myself, but he sent me."},{"v":43,"t":"Why don’t you understand my speech? Because you can’t hear my word."},{"v":44,"t":"You are of your father the devil, and you want to do the desires of your father. He was a murderer from the beginning, and doesn’t stand in the truth, because there is no truth in him. When he speaks a lie, he speaks on his own; for he is a liar, and the father of lies."},{"v":45,"t":"But because I tell the truth, you don’t believe me."},{"v":46,"t":"Which of you convicts me of sin? If I tell the truth, why do you not believe me?"},{"v":47,"t":"He who is of God hears the words of God. For this cause you don’t hear, because you are not of God.”"},{"v":48,"t":"Then the Jews answered him, “Don’t we say well that you are a Samaritan, and have a demon?”"},{"v":49,"t":"Jesus answered, “I don’t have a demon, but I honor my Father and you dishonor me."},{"v":50,"t":"But I don’t seek my own glory. There is one who seeks and judges."},{"v":51,"t":"Most certainly, I tell you, if a person keeps my word, he will never see death.”"},{"v":52,"t":"Then the Jews said to him, “Now we know that you have a demon. Abraham died, as did the prophets; and you say, ‘If a man keeps my word, he will never taste of death.’"},{"v":53,"t":"Are you greater than our father Abraham, who died? The prophets died. Who do you make yourself out to be?”"},{"v":54,"t":"Jesus answered, “If I glorify myself, my glory is nothing. It is my Father who glorifies me, of whom you say that he is our God."},{"v":55,"t":"You have not known him, but I know him. If I said, ‘I don’t know him,’ I would be like you, a liar. But I know him and keep his word."},{"v":56,"t":"Your father Abraham rejoiced to see my day. He saw it and was glad.”"},{"v":57,"t":"The Jews therefore said to him, “You are not yet fifty years old! Have you seen Abraham?”"},{"v":58,"t":"Jesus said to them, “Most certainly, I tell you, before Abraham came into existence, I AM.”"},{"v":59,"t":"Therefore they took up stones to throw at him, but Jesus hid himself and went out of the temple, having gone through the middle of them, and so passed by."}],"hr":[{"v":1,"t":"A Isus se uputi na Maslinsku goru."},{"v":2,"t":"U zoru eto ga opet u Hramu. Sav je narod hrlio k njemu. On sjede i stade poučavati."},{"v":3,"t":"Uto mu pismoznanci i farizeji dovedu neku ženu zatečenu u preljubu. Postave je u sredinu"},{"v":4,"t":"i kažu mu: “Učitelju! Ova je žena zatečena u samom preljubu."},{"v":5,"t":"U Zakonu nam je Mojsije naredio takve kamenovati. Što ti na to kažeš?”"},{"v":6,"t":"To govorahu samo da ga iskušaju pa da ga mogu optužiti. Isus se sagne pa stane prstom pisati po tlu."},{"v":7,"t":"A kako su oni dalje navaljivali, on se uspravi i reče im: “Tko je od vas bez grijeha, neka prvi na nju baci kamen.”"},{"v":8,"t":"I ponovno se sagnuvši, nastavi pisati po zemlji."},{"v":9,"t":"A kad oni to čuše, stadoše odlaziti jedan za drugim, počevši od starijih. Osta Isus sam - i žena koja stajaše u sredini."},{"v":10,"t":"Isus se uspravi i reče joj: “Ženo, gdje su oni? Zar te nitko ne osudi?”"},{"v":11,"t":"Ona reče: “Nitko, Gospodine.” Reče joj Isus: “Ni ja te ne osuđujem. Idi i odsada više nemoj griješiti.”"},{"v":12,"t":"Isus im zatim ponovno progovori: “Ja sam svjetlost svijeta; tko ide za mnom, neće hoditi u tami, nego će imati svjetlost života.”"},{"v":13,"t":"Farizeji mu nato rekoše: “Ti svjedočiš sam za sebe: svjedočanstvo tvoje nije istinito!”"},{"v":14,"t":"Odgovori im Isus: “Ako ja i svjedočim sam za sebe, svjedočanstvo je moje istinito jer znam odakle dođoh i kamo idem. A vi ne znate ni odakle dolazim ni kamo idem."},{"v":15,"t":"Vi sudite po tijelu; ja ne sudim nikoga;"},{"v":16,"t":"no ako i sudim, sud je moj istinit jer nisam sam, nego - ja i onaj koji me posla, Otac."},{"v":17,"t":"Ta i u vašem zakonu piše da je svjedočanstvo dvojice istinito."},{"v":18,"t":"Ja svjedočim za sebe, a svjedoči za mene i onaj koji me posla, Otac.”"},{"v":19,"t":"Nato ga upitaju: “Gdje je tvoj Otac?” Odgovori Isus: “Niti mene poznajete niti Oca mojega. Kad biste poznavali mene, i Oca biste moga poznavali.”"},{"v":20,"t":"Te riječi rekao je Isus u riznici dok je naučavao u Hramu. I nitko ga ne uhvati jer još ne bijaše došao njegov čas."},{"v":21,"t":"Reče im ponovno Isus: “Ja odlazim, a vi ćete me tražiti i u svojem ćete grijehu umrijeti. Kamo ja odlazim, vi ne možete doći.”"},{"v":22,"t":"Židovi se nato stanu pitati: “Da se možda ne kani ubiti kad govori: 'Kamo ja odlazim, vi ne možete doći'?”"},{"v":23,"t":"A Isus nastavi: “Vi ste odozdol, ja sam odozgor. Vi ste od ovoga svijeta, a ja nisam od ovoga svijeta."},{"v":24,"t":"Stoga vam i rekoh: 'Umrijet ćete u grijesima svojim.' Uistinu, ako ne povjerujete da Ja jesam, umrijet ćete u grijesima svojim.”"},{"v":25,"t":"Nato mu oni rekoše: “A tko si ti?” Odvrati Isus:"},{"v":26,"t":"“Ta što da vam s početka opet zborim? Mnogo toga imam o vama zboriti i suditi; no onaj koji me posla istinit je, i što sam čuo od njega, to ja zborim svijetu.”"},{"v":27,"t":"Ne shvatiše da im govori o Ocu."},{"v":28,"t":"Isus im nato reče: “Kad uzdignete Sina Čovječjega, tada ćete upoznati da Ja jesam i da sam od sebe ne činim ništa, nego da onako zborim kako me naučio Otac."},{"v":29,"t":"Onaj koji me posla sa mnom je i ne ostavi me sama jer ja uvijek činim što je njemu milo.”"},{"v":30,"t":"Na te njegove riječi mnogi povjerovaše u njega."},{"v":31,"t":"Tada Isus progovori Židovima koji mu povjerovaše: “Ako ostanete u mojoj riječi, uistinu, moji ste učenici;"},{"v":32,"t":"upoznat ćete istinu i istina će vas osloboditi.”"},{"v":33,"t":"Odgovore mu: “Potomstvo smo Abrahamovo i nikome nikada nismo robovali. Kako to ti govoriš: 'Postat ćete slobodni?'”"},{"v":34,"t":"Odgovori im Isus: “Zaista, zaista, kažem vam: tko god čini grijeh, rob je grijeha."},{"v":35,"t":"Rob ne ostaje u kući zauvijek, a sin ostaje zauvijek."},{"v":36,"t":"Ako vas dakle Sin oslobodi, zbilja ćete biti slobodni."},{"v":37,"t":"Znam: potomstvo ste Abrahamovo, a ipak tražite da me ubijete jer moja riječ nema mjesta u vama."},{"v":38,"t":"Ja govorim što vidjeh kod Oca, a vi činite što čuste od svog oca.”"},{"v":39,"t":"Odgovoriše mu: “Naš je otac Abraham”. Kaže im Isus: “Da ste djeca Abrahamova, djela biste Abrahamova činili."},{"v":40,"t":"A eto, tražite da ubijete mene, mene koji sam vam govorio istinu što sam je od Boga čuo. Takvo što Abraham nije učinio!"},{"v":41,"t":"Vi činite djela oca svojega.” Rekoše mu: “Mi se nismo rodili iz preljuba, jedan nam je Otac - Bog.”"},{"v":42,"t":"Reče im Isus: “Kad bi Bog bio vaš Otac, ljubili biste mene jer sam ja od Boga izišao i došao; nisam sam od sebe došao, nego on me posla."},{"v":43,"t":"Zašto moje besjede ne razumijete? Zato što niste kadri slušati moju riječ."},{"v":44,"t":"Vama je otac đavao i hoće vam se vršiti prohtjeve oca svoga. On bijaše čovjekoubojica od početka i ne stajaše u istini jer nema istine u njemu: kad govori laž, od svojega govori jer je lažac i otac laži."},{"v":45,"t":"A meni, jer istinu govorim, meni ne vjerujete."},{"v":46,"t":"Tko će mi od vas dokazati grijeh? Ako istinu govorim, zašto mi ne vjerujete?"},{"v":47,"t":"Tko je od Boga, riječi Božje sluša; vi zato ne slušate jer niste od Boga.”"},{"v":48,"t":"Odgovoriše mu Židovi: “Ne kažemo li pravo da si ti Samarijanac i da imaš zloduha?”"},{"v":49,"t":"Odgovori Isus: “Ja nemam zloduha, nego častim svoga Oca, a vi me obeščašćujete."},{"v":50,"t":"No ja ne tražim svoje slave; ima tko traži i sudi."},{"v":51,"t":"Zaista, zaista, kažem vam: ako tko očuva moju riječ, neće vidjeti smrti dovijeka.”"},{"v":52,"t":"Rekoše mu Židovi: “Sada vidimo da imaš zloduha. Abraham umrije, tako i proroci, a ti kažeš: 'Ako tko čuva moju riječ, neće okusiti smrti dovijeka.'"},{"v":53,"t":"Zar si ti veći od oca našega Abrahama, koji je umro? Pa i proroci pomriješe. Kime se to praviš?”"},{"v":54,"t":"Odgovori Isus: “Ako ja sam sebe slavim, slava moja nije ništa. Ima koji me slavi - Otac moj, a vi velite da je on vaš Bog,"},{"v":55,"t":"no ne poznajete ga, a ja ga znam. Ako vam reknem da ga ne znam, bit ću lažac jednak vama. No znam ga i riječ njegovu čuvam."},{"v":56,"t":"Abraham, otac vaš, usklikta što će vidjeti moj Dan. I vidje i obradova se.”"},{"v":57,"t":"Rekoše mu nato Židovi: “Ni pedeset ti još godina nije, a vidio si Abrahama?”"},{"v":58,"t":"Reče im Isus: “Zaista, zaista, kažem vam: prije negoli Abraham posta, Ja jesam!”"},{"v":59,"t":"Nato pograbiše kamenje da bace na nj. No Isus se sakri te iziđe iz Hrama."}]},"9":{"fa":[{"v":1,"t":"و وقتی که می‌رفت کوری مادرزاد دید."},{"v":2,"t":"وشاگردانش از او سوال کرده، گفتند: «ای استاد گناه که کرد، این شخص یا والدین او که کورزاییده شد؟»"},{"v":3,"t":"عیسی جواب داد که «گناه نه این شخص کرد و نه پدر و مادرش، بلکه تا اعمال خدادر وی ظاهر شود."},{"v":4,"t":"مادامی که روز است، مرا بایدبه‌کارهای فرستنده خود مشغول باشم. شب می‌آید که در آن هیچ‌کس نمی تواند کاری کند."},{"v":5,"t":"مادامی که در جهان هستم، نور جهانم.»"},{"v":6,"t":"این راگفت و آب دهان بر زمین انداخته، از آب گل ساخت و گل را به چشمان کور مالید،"},{"v":7,"t":"و بدوگفت: «برو در حوض سیلوحا (که به‌معنی مرسل است ) بشوی.» پس رفته شست و بینا شده، برگشت."},{"v":8,"t":"پس همسایگان و کسانی که او را پیش از آن در حالت کوری دیده بودند، گفتند: «آیا این آن نیست که می‌نشست و گدایی می‌کرد؟»"},{"v":9,"t":"بعضی گفتند: «همان است.» و بعضی گفتند: «شباهت بدودارد.» او گفت: «من همانم.»"},{"v":10,"t":"بدو گفتند: «پس چگونه چشمان تو بازگشت؟»"},{"v":11,"t":"او جواب داد: «شخصی که او را عیسی می‌گویند، گل ساخت وبر چشمان من مالیده، به من گفت به حوض سیلوحا برو و بشوی. آنگاه رفتم و شسته بیناگشتم.»"},{"v":12,"t":"به وی گفتند: «آن شخص کجا است؟» گفت: «نمی دانم.»"},{"v":13,"t":"پس او را که پیشتر کور بود، نزد فریسیان آوردند."},{"v":14,"t":"و آن روزی که عیسی گل ساخته، چشمان او را باز کرد روز سبت بود."},{"v":15,"t":"آنگاه فریسیان نیز از او سوال کردند که «چگونه بیناشدی؟» بدیشان گفت: «گل به چشمهای من گذارد. پس شستم و بینا شدم.»"},{"v":16,"t":"بعضی ازفریسیان گفتند: «آن شخص از جانب خدا نیست، زیرا که سبت را نگاه نمی دارد.» دیگران گفتند: «چگونه شخص گناهکار می‌تواند مثل این معجزات ظاهر سازد.» و در میان ایشان اختلاف افتاد."},{"v":17,"t":"باز بدان کور گفتند: «تو درباره او چه می‌گویی که چشمان تو را بینا ساخت؟» گفت: «نبی است.»"},{"v":18,"t":"لیکن یهودیان سرگذشت او را باور نکردندکه کور بوده و بینا شده است، تا آنکه پدر و مادرآن بینا شده را طلبیدند."},{"v":19,"t":"و از ایشان سوال کرده، گفتند: «آیا این است پسر شما که می‌گویید کورمتولد شده؟ پس چگونه الحال بینا گشته است؟»"},{"v":20,"t":"پدر و مادر او در جواب ایشان گفتند: «می‌دانیم که این پسر ما است و کور متولد شده."},{"v":21,"t":"لیکن الحال چطور می‌بیند، نمی دانیم ونمی دانیم که چشمان او را باز نموده. او بالغ است از وی سوال کنید تا او احوال خود را بیان کند.»"},{"v":22,"t":"پدر و مادر او چنین گفتند زیرا که از یهودیان می‌ترسیدند، از آنرو که یهودیان با خود عهد کرده بودند که هر‌که اعتراف کند که او مسیح است، ازکنیسه بیرونش کنند."},{"v":23,"t":"و از اینجهت والدین اوگفتند: «او بالغ است از خودش بپرسید.»"},{"v":24,"t":"پس آن شخص را که کور بود، باز خوانده، بدو گفتند: «خدا را تمجید کن. ما می‌دانیم که این شخص گناهکار است.»"},{"v":25,"t":"او جواب داد اگرگناهکار است نمی دانم. یک چیز می‌دانم که کوربودم و الان بینا شده‌ام.»"},{"v":26,"t":"باز بدو گفتند: «با توچه کرد و چگونه چشمهای تو را باز کرد؟»"},{"v":27,"t":"ایشان را جواب داد که «الان به شما گفتم. نشنیدید؟ و برای چه باز می‌خواهید بشنوید؟ آیاشما نیز اراده دارید شاگرد او بشوید؟»"},{"v":28,"t":"پس اورا دشنام داده، گفتند: «تو شاگرد او هستی. ماشاگرد موسی می‌باشیم."},{"v":29,"t":"ما می‌دانیم که خدا باموسی تکلم کرد. اما این شخص را نمی دانیم ازکجا است.»"},{"v":30,"t":"آن مرد جواب داده، بدیشان گفت: «این عجب است که شما نمی دانید از کجا است وحال آنکه چشمهای مرا باز کرد."},{"v":31,"t":"و می‌دانیم که خدا دعای گناهکاران را نمی شنود؛ و لیکن اگرکسی خداپرست باشد و اراده او را به‌جا آرد، او رامی شنود."},{"v":32,"t":"از ابتدای عالم شنیده نشده است که کسی چشمان کور مادرزاد را باز کرده باشد."},{"v":33,"t":"اگر این شخص از خدا نبودی، هیچ کارنتوانستی کرد.»"},{"v":34,"t":"در جواب وی گفتند: «تو به کلی با گناه متولد شده‌ای. آیا تو ما را تعلیم می‌دهی؟» پس او را بیرون راندند."},{"v":35,"t":"عیسی چون شنید که او را بیرون کرده‌اند، وی را جسته گفت: «آیا تو به پسر خدا ایمان داری؟»"},{"v":36,"t":"او در جواب گفت: «ای آقا کیست تا به او ایمان آورم؟»"},{"v":37,"t":"عیسی بدو گفت: «تو نیز او رادیده‌ای و آنکه با تو تکلم می‌کند همان است.»"},{"v":38,"t":"گفت: «ای خداوند ایمان آوردم.» پس او راپرستش نمود."},{"v":39,"t":"آنگاه عیسی گفت: «من در این جهان بجهت داوری آمدم تا کوران بینا و بینایان، کور شوند.»"},{"v":40,"t":"بعضی از فریسیان که با او بودند، چون این کلام را شنیدند گفتند: «آیا ما نیز کورهستیم؟»"},{"v":41,"t":"عیسی بدیشان گفت: «اگر کورمی بودید گناهی نمی داشتید و لکن الان می‌گوییدبینا هستیم. پس گناه شما می‌ماند."}],"en":[{"v":1,"t":"As he passed by, he saw a man blind from birth."},{"v":2,"t":"His disciples asked him, “Rabbi, who sinned, this man or his parents, that he was born blind?”"},{"v":3,"t":"Jesus answered, “This man didn’t sin, nor did his parents, but that the works of God might be revealed in him."},{"v":4,"t":"I must work the works of him who sent me while it is day. The night is coming, when no one can work."},{"v":5,"t":"While I am in the world, I am the light of the world.”"},{"v":6,"t":"When he had said this, he spat on the ground, made mud with the saliva, anointed the blind man’s eyes with the mud,"},{"v":7,"t":"and said to him, “Go, wash in the pool of Siloam” (which means “Sent”). So he went away, washed, and came back seeing."},{"v":8,"t":"Therefore the neighbors and those who saw that he was blind before said, “Isn’t this he who sat and begged?”"},{"v":9,"t":"Others were saying, “It is he.” Still others were saying, “He looks like him.” He said, “I am he.”"},{"v":10,"t":"They therefore were asking him, “How were your eyes opened?”"},{"v":11,"t":"He answered, “A man called Jesus made mud, anointed my eyes, and said to me, ‘Go to the pool of Siloam and wash.’ So I went away and washed, and I received sight.”"},{"v":12,"t":"Then they asked him, “Where is he?” He said, “I don’t know.”"},{"v":13,"t":"They brought him who had been blind to the Pharisees."},{"v":14,"t":"It was a Sabbath when Jesus made the mud and opened his eyes."},{"v":15,"t":"Again therefore the Pharisees also asked him how he received his sight. He said to them, “He put mud on my eyes, I washed, and I see.”"},{"v":16,"t":"Some therefore of the Pharisees said, “This man is not from God, because he doesn’t keep the Sabbath.” Others said, “How can a man who is a sinner do such signs?” So there was division among them."},{"v":17,"t":"Therefore they asked the blind man again, “What do you say about him, because he opened your eyes?” He said, “He is a prophet.”"},{"v":18,"t":"The Jews therefore didn’t believe concerning him, that he had been blind and had received his sight, until they called the parents of him who had received his sight,"},{"v":19,"t":"and asked them, “Is this your son, whom you say was born blind? How then does he now see?”"},{"v":20,"t":"His parents answered them, “We know that this is our son, and that he was born blind;"},{"v":21,"t":"but how he now sees, we don’t know; or who opened his eyes, we don’t know. He is of age. Ask him. He will speak for himself.”"},{"v":22,"t":"His parents said these things because they feared the Jews; for the Jews had already agreed that if any man would confess him as Christ, he would be put out of the synagogue."},{"v":23,"t":"Therefore his parents said, “He is of age. Ask him.”"},{"v":24,"t":"So they called the man who was blind a second time, and said to him, “Give glory to God. We know that this man is a sinner.”"},{"v":25,"t":"He therefore answered, “I don’t know if he is a sinner. One thing I do know: that though I was blind, now I see.”"},{"v":26,"t":"They said to him again, “What did he do to you? How did he open your eyes?”"},{"v":27,"t":"He answered them, “I told you already, and you didn’t listen. Why do you want to hear it again? You don’t also want to become his disciples, do you?”"},{"v":28,"t":"They insulted him and said, “You are his disciple, but we are disciples of Moses."},{"v":29,"t":"We know that God has spoken to Moses. But as for this man, we don’t know where he comes from.”"},{"v":30,"t":"The man answered them, “How amazing! You don’t know where he comes from, yet he opened my eyes."},{"v":31,"t":"We know that God doesn’t listen to sinners, but if anyone is a worshiper of God and does his will, he listens to him."},{"v":32,"t":"Since the world began it has never been heard of that anyone opened the eyes of someone born blind."},{"v":33,"t":"If this man were not from God, he could do nothing.”"},{"v":34,"t":"They answered him, “You were altogether born in sins, and do you teach us?” Then they threw him out."},{"v":35,"t":"Jesus heard that they had thrown him out, and finding him, he said, “Do you believe in the Son of God?”"},{"v":36,"t":"He answered, “Who is he, Lord, that I may believe in him?”"},{"v":37,"t":"Jesus said to him, “You have both seen him, and it is he who speaks with you.”"},{"v":38,"t":"He said, “Lord, I believe!” and he worshiped him."},{"v":39,"t":"Jesus said, “I came into this world for judgment, that those who don’t see may see; and that those who see may become blind.”"},{"v":40,"t":"Those of the Pharisees who were with him heard these things, and said to him, “Are we also blind?”"},{"v":41,"t":"Jesus said to them, “If you were blind, you would have no sin; but now you say, ‘We see.’ Therefore your sin remains."}],"hr":[{"v":1,"t":"Prolazeći ugleda čovjeka slijepa od rođenja."},{"v":2,"t":"Zapitaše ga njegovi učenici: “Učitelju, tko li sagriješi, on ili njegovi roditelji te se slijep rodio?”"},{"v":3,"t":"Odgovori Isus: “Niti sagriješi on niti njegovi roditelji, nego je to zato da se na njemu očituju djela Božja.”"},{"v":4,"t":"“Dok je dan, treba da radimo djela onoga koji me posla. Dolazi noć, kad nitko ne može raditi."},{"v":5,"t":"Dok sam na svijetu, svjetlost sam svijeta.”"},{"v":6,"t":"To rekavši, pljune na zemlju i od pljuvačke načini kal pa mu kalom premaza oči."},{"v":7,"t":"I reče mu: “Idi, operi se u kupalištu Siloamu!” - što znači “Poslanik.” Onaj ode, umije se pa se vrati gledajući."},{"v":8,"t":"Susjedi i oni koji su ga prije viđali kao prosjaka govorili su: “Nije li to onaj koji je sjedio i prosio?”"},{"v":9,"t":"Jedni su govorili: “On je.” Drugi opet: “Nije, nego mu je sličan.” On je sam tvrdio: “Da, ja sam!”"},{"v":10,"t":"Nato ga upitaše: “Kako su ti se otvorile oči?”"},{"v":11,"t":"On odgovori: “Čovjek koji se zove Isus načini kal, premaza mi oči i reče mi: 'Idi u Siloam i operi se.' Odoh dakle, oprah se i progledah.”"},{"v":12,"t":"Rekoše mu: “Gdje je on?” Odgovori: “Ne znam.”"},{"v":13,"t":"Tada odvedoše toga bivšeg slijepca farizejima."},{"v":14,"t":"A toga dana kad Isus načini kal i otvori njegove oči, bijaše subota."},{"v":15,"t":"Farizeji ga počeše iznova ispitivati kako je progledao. On im reče: “Stavio mi kal na oči i ja se oprah - i evo vidim.”"},{"v":16,"t":"Nato neki između farizeja rekoše: “Nije taj čovjek od Boga: ne pazi na subotu.” Drugi su pak govorili: “A kako bi jedan grešnik mogao činiti takva znamenja?” I nastade među njima podvojenost."},{"v":17,"t":"Zatim ponovno upitaju slijepca: “A što ti kažeš o njemu? Otvorio ti je oči!” On odgovori: “Prorok je!”"},{"v":18,"t":"Židovi ipak ne vjerovahu da on bijaše slijep i da je progledao dok ne dozvaše roditelje toga koji je progledao"},{"v":19,"t":"i upitaše ih: “Je li ovo vaš sin za kojega tvrdite da se slijep rodio? Kako sada vidi?”"},{"v":20,"t":"Njegovi roditelji odvrate: “Znamo da je ovo naš sin i da se slijep rodio."},{"v":21,"t":"A kako sada vidi, to mi ne znamo; i tko mu je otvorio oči, ne znamo. Njega pitajte! Punoljetan je: neka sam o sebi govori!”"},{"v":22,"t":"Rekoše tako njegovi roditelji jer su se bojali Židova. Židovi se doista već bijahu dogovorili da se iz sinagoge ima izopćiti svaki koji njega prizna Kristom."},{"v":23,"t":"Zbog toga rekoše njegovi roditelji: “Punoljetan je, njega pitajte!”"},{"v":24,"t":"Pozvaše stoga po drugi put čovjeka koji bijaše slijep i rekoše mu: “Podaj slavu Bogu! Mi znamo da je taj čovjek grešnik!”"},{"v":25,"t":"Nato im on odgovori: “Je li grešnik, ja ne znam. Jedno znam: slijep sam bio, a sada vidim.”"},{"v":26,"t":"Rekoše mu opet: “Što ti učini? Kako ti otvori oči?”"},{"v":27,"t":"Odgovori im: “Već vam rekoh i ne poslušaste me. Što opet hoćete čuti? Da ne kanite i vi postati njegovim učenicima?”"},{"v":28,"t":"Nato ga oni izgrdiše i rekoše: “Ti si njegov učenik, a mi smo učenici Mojsijevi."},{"v":29,"t":"Mi znamo da je Mojsiju govorio Bog, a za ovoga ne znamo ni odakle je.”"},{"v":30,"t":"Odgovori im čovjek: “Pa to i jest čudnovato da vi ne znate odakle je, a meni je otvorio oči."},{"v":31,"t":"Znamo da Bog grešnike ne uslišava; nego je li tko bogobojazan i vrši li njegovu volju, toga uslišava."},{"v":32,"t":"Odvijeka se nije čulo da bi tko otvorio oči slijepcu od rođenja."},{"v":33,"t":"Kad ovaj ne bi bio od Boga, ne bi mogao činiti ništa”."},{"v":34,"t":"Odgovore mu: “Sav si se u grijesima rodio, i ti nas da učiš?” i izbaciše ga."},{"v":35,"t":"Dočuo Isus da su onoga izbacili pa ga nađe i reče mu: “Ti vjeruješ u Sina Čovječjega?”"},{"v":36,"t":"On odgovori: “A tko je taj, Gospodine, da vjerujem u njega?”"},{"v":37,"t":"Reče mu Isus: “Vidio si ga! To je onaj koji govori s tobom!”"},{"v":38,"t":"A on reče: “Vjerujem, Gospodine!” I baci se ničice preda nj."},{"v":39,"t":"Tada Isus reče: “Radi suda dođoh na ovaj svijet: da progledaju koji ne vide, a koji vide, da oslijepe!”"},{"v":40,"t":"Čuli to neki od farizeja koji su bili s njime pa ga upitaju: “Zar smo i mi slijepi?”"},{"v":41,"t":"Isus im odgovori: “Da ste slijepi, ne biste imali grijeha. No vi govorite: 'Vidimo' pa grijeh vaš ostaje.”"}]},"10":{"fa":[{"v":1,"t":"«آمین آمین به شما می‌گویم هر‌که از دربه آغل گوسفند داخل نشود، بلکه از راه دیگر بالا رود، او دزد و راهزن است."},{"v":2,"t":"و اما آنکه از در داخل شود، شبان گوسفندان است."},{"v":3,"t":"دربان بجهت او می‌گشاید و گوسفندان آواز او رامی شنوند و گوسفندان خود را نام بنام می‌خواند وایشان را بیرون می‌برد."},{"v":4,"t":"و وقتی که گوسفندان خود را بیرون برد، پیش روی ایشان می‌خرامد وگوسفندان از عقب او می‌روند، زیرا که آواز او رامی شناسند."},{"v":5,"t":"لیکن غریب را متابعت نمی کنند، بلکه از او می‌گریزند زیرا که آواز غریبان رانمی شناسند.»"},{"v":6,"t":"و این مثل را عیسی برای ایشان آورد، اماایشان نفهمیدند که چه چیز بدیشان می‌گوید."},{"v":7,"t":"آنگاه عیسی بدیشان باز‌گفت: «آمین آمین به شما می‌گویم که من در گوسفندان هستم."},{"v":8,"t":"جمیع کسانی که پیش از من آمدند، دزد و راهزن هستند، لیکن گوسفندان سخن ایشان را نشنیدند."},{"v":9,"t":"من درهستم هر‌که از من داخل گردد نجات یابد و بیرون و درون خرامد و علوفه یابد."},{"v":10,"t":"دزد نمی آید مگرآنکه بدزدد و بکشد و هلاک کند. من آمدم تاایشان حیات یابند و آن را زیادتر حاصل کنند."},{"v":11,"t":"«من شبان نیکو هستم. شبان نیکو جان خودرا در راه گوسفندان می‌نهد."},{"v":12,"t":"اما مزدوری که شبان نیست و گوسفندان از آن او نمی باشند، چون بیند که گرگ می‌آید، گوسفندان را گذاشته، فرار می‌کند و گرگ گوسفندان را می‌گیرد وپراکنده می‌سازد."},{"v":13,"t":"مزدور می‌گریزد چونکه مزدور است و به فکر گوسفندان نیست."},{"v":14,"t":"من شبان نیکو هستم و خاصان خود را می‌شناسم وخاصان من مرا می‌شناسند."},{"v":15,"t":"چنانکه پدر مرامی شناسد و من پدر را می‌شناسم و جان خود رادر راه گوسفندان می‌نهم."},{"v":16,"t":"و مرا گوسفندان دیگر هست که از این آغل نیستند. باید آنها را نیزبیاورم و آواز مرا خواهند شنید و یک گله و یک شبان خواهند شد."},{"v":17,"t":"و از این سبب پدر مرادوست می‌دارد که من جان خود را می‌نهم تا آن راباز گیرم."},{"v":18,"t":"کسی آن را از من نمی گیرد، بلکه من خود آن را می‌نهم. قدرت دارم که آن را بنهم وقدرت دارم آن را باز گیرم. این حکم را از پدرخود یافتم.»"},{"v":19,"t":"باز به‌سبب این کلام، در میان یهودیان اختلاف افتاد."},{"v":20,"t":"بسیاری از ایشان گفتند که «دیودارد و دیوانه است. برای چه بدو گوش می‌دهید؟»"},{"v":21,"t":"دیگران گفتند که «این سخنان دیوانه نیست. آیا دیو می‌تواند چشم کوران را بازکند؟»"},{"v":22,"t":"پس در اورشلیم، عید تجدید شد و زمستان بود."},{"v":23,"t":"و عیسی در هیکل، در رواق سلیمان می‌خرامید."},{"v":24,"t":"پس یهودیان دور او را گرفته، بدوگفتند: «تا کی ما را متردد داری؟ اگر تو مسیح هستی، آشکارا به ما بگو."},{"v":25,"t":"عیسی بدیشان جواب داد: «من به شما گفتم و ایمان نیاوردید. اعمالی را که به اسم پدر خود به‌جا می‌آورم، آنهابرای من شهادت می‌دهد."},{"v":26,"t":"لیکن شما ایمان نمی آورید زیرا از گوسفندان من نیستید، چنانکه به شما گفتم."},{"v":27,"t":"گوسفندان من آواز مرا می‌شنوندو من آنها را می‌شناسم و مرا متابعت می‌کنند."},{"v":28,"t":"ومن به آنها حیات جاودانی می‌دهم و تا به ابد هلاک نخواهند شد و هیچ‌کس آنها را از دست من نخواهد گرفت."},{"v":29,"t":"پدری که به من داد از همه بزرگتر است و کسی نمی تواند از دست پدر من بگیرد."},{"v":30,"t":"من و پدر یک هستیم.»"},{"v":31,"t":"آنگاه یهودیان باز سنگها برداشتند تا او راسنگسار کنند."},{"v":32,"t":"عیسی بدیشان جواب داد: «ازجانب پدر خود بسیار کارهای نیک به شما نمودم. به‌سبب کدام‌یک از آنها مرا سنگسار می‌کنید؟»"},{"v":33,"t":"یهودیان در جواب گفتند: «به‌سبب عمل نیک، تو را سنگسار نمی کنیم، بلکه به‌سبب کفر، زیرا توانسان هستی و خود را خدا می‌خوانی.»"},{"v":34,"t":"عیسی در جواب ایشان گفت: «آیا در تورات شما نوشته نشده است که من گفتم شما خدایان هستید؟"},{"v":35,"t":"پس اگر آنانی را که کلام خدا بدیشان نازل شد، خدایان خواند و ممکن نیست که کتاب محو گردد،"},{"v":36,"t":"آیا کسی را که پدر تقدیس کرده، به جهان فرستاد، بدو می‌گویید کفر می‌گویی، از آن سبب که گفتم پسر خدا هستم؟"},{"v":37,"t":"اگر اعمال پدرخود را به‌جا نمی آورم، به من ایمان میاورید."},{"v":38,"t":"ولکن چنانچه به‌جا می‌آورم، هرگاه به من ایمان نمی آورید، به اعمال ایمان آورید تا بدانید و یقین کنید که پدر در من است و من در او.»"},{"v":39,"t":"پس دیگرباره خواستند او را بگیرند، اما از دستهای ایشان بیرون رفت."},{"v":40,"t":"و باز به آن طرف اردن، جایی که اول یحیی تعمید می‌داد، رفت و در آنجا توقف نمود."},{"v":41,"t":"وبسیاری نزد او آمده، گفتند که یحیی هیچ معجزه ننمود و لکن هر‌چه یحیی درباره این شخص گفت راست است."},{"v":42,"t":"پس بسیاری در آنجا به او ایمان آوردند."}],"en":[{"v":1,"t":"“Most certainly, I tell you, one who doesn’t enter by the door into the sheep fold, but climbs up some other way, is a thief and a robber."},{"v":2,"t":"But one who enters in by the door is the shepherd of the sheep."},{"v":3,"t":"The gatekeeper opens the gate for him, and the sheep listen to his voice. He calls his own sheep by name and leads them out."},{"v":4,"t":"Whenever he brings out his own sheep, he goes before them; and the sheep follow him, for they know his voice."},{"v":5,"t":"They will by no means follow a stranger, but will flee from him; for they don’t know the voice of strangers.”"},{"v":6,"t":"Jesus spoke this parable to them, but they didn’t understand what he was telling them."},{"v":7,"t":"Jesus therefore said to them again, “Most certainly, I tell you, I am the sheep’s door."},{"v":8,"t":"All who came before me are thieves and robbers, but the sheep didn’t listen to them."},{"v":9,"t":"I am the door. If anyone enters in by me, he will be saved, and will go in and go out and will find pasture."},{"v":10,"t":"The thief only comes to steal, kill, and destroy. I came that they may have life, and may have it abundantly."},{"v":11,"t":"“I am the good shepherd. The good shepherd lays down his life for the sheep."},{"v":12,"t":"He who is a hired hand, and not a shepherd, who doesn’t own the sheep, sees the wolf coming, leaves the sheep, and flees. The wolf snatches the sheep and scatters them."},{"v":13,"t":"The hired hand flees because he is a hired hand and doesn’t care for the sheep."},{"v":14,"t":"I am the good shepherd. I know my own, and I’m known by my own;"},{"v":15,"t":"even as the Father knows me, and I know the Father. I lay down my life for the sheep."},{"v":16,"t":"I have other sheep which are not of this fold. I must bring them also, and they will hear my voice. They will become one flock with one shepherd."},{"v":17,"t":"Therefore the Father loves me, because I lay down my life, that I may take it again."},{"v":18,"t":"No one takes it away from me, but I lay it down by myself. I have power to lay it down, and I have power to take it again. I received this commandment from my Father.”"},{"v":19,"t":"Therefore a division arose again among the Jews because of these words."},{"v":20,"t":"Many of them said, “He has a demon and is insane! Why do you listen to him?”"},{"v":21,"t":"Others said, “These are not the sayings of one possessed by a demon. It isn’t possible for a demon to open the eyes of the blind, is it?”"},{"v":22,"t":"It was the Feast of the Dedication at Jerusalem."},{"v":23,"t":"It was winter, and Jesus was walking in the temple, in Solomon’s porch."},{"v":24,"t":"The Jews therefore came around him and said to him, “How long will you hold us in suspense? If you are the Christ, tell us plainly.”"},{"v":25,"t":"Jesus answered them, “I told you, and you don’t believe. The works that I do in my Father’s name, these testify about me."},{"v":26,"t":"But you don’t believe, because you are not of my sheep, as I told you."},{"v":27,"t":"My sheep hear my voice, and I know them, and they follow me."},{"v":28,"t":"I give eternal life to them. They will never perish, and no one will snatch them out of my hand."},{"v":29,"t":"My Father who has given them to me is greater than all. No one is able to snatch them out of my Father’s hand."},{"v":30,"t":"I and the Father are one.”"},{"v":31,"t":"Therefore the Jews took up stones again to stone him."},{"v":32,"t":"Jesus answered them, “I have shown you many good works from my Father. For which of those works do you stone me?”"},{"v":33,"t":"The Jews answered him, “We don’t stone you for a good work, but for blasphemy, because you, being a man, make yourself God.”"},{"v":34,"t":"Jesus answered them, “Isn’t it written in your law, ‘I said, you are gods’?"},{"v":35,"t":"If he called them gods, to whom the word of God came (and the Scripture can’t be broken),"},{"v":36,"t":"do you say of him whom the Father sanctified and sent into the world, ‘You blaspheme,’ because I said, ‘I am the Son of God’?"},{"v":37,"t":"If I don’t do the works of my Father, don’t believe me."},{"v":38,"t":"But if I do them, though you don’t believe me, believe the works, that you may know and believe that the Father is in me, and I in the Father.”"},{"v":39,"t":"They sought again to seize him, and he went out of their hand."},{"v":40,"t":"He went away again beyond the Jordan into the place where John was baptizing at first, and he stayed there."},{"v":41,"t":"Many came to him. They said, “John indeed did no sign, but everything that John said about this man is true.”"},{"v":42,"t":"Many believed in him there."}],"hr":[{"v":1,"t":"“Zaista, zaista, kažem vam: tko god u ovčinjak ne ulazi na vrata, nego negdje drugdje preskače, kradljivac je i razbojnik."},{"v":2,"t":"A tko na vrata ulazi, pastir je ovaca."},{"v":3,"t":"Tome vratar otvara i ovce slušaju njegov glas. On ovce svoje zove imenom pa ih izvodi."},{"v":4,"t":"A kad sve svoje izvede, pred njima ide i ovce idu za njim jer poznaju njegov glas."},{"v":5,"t":"Za tuđincem, dakako, ne idu, već bježe od njega jer tuđinčeva glasa ne poznaju.”"},{"v":6,"t":"Isus im kaza tu poredbu, ali oni ne razumješe što im htjede time kazati."},{"v":7,"t":"Stoga im Isus ponovno reče: “Zaista, zaista, kažem vam: ja sam vrata ovcama."},{"v":8,"t":"Svi koji dođoše prije mene, kradljivci su i razbojnici; ali ih ovce ne poslušaše."},{"v":9,"t":"Ja sam vrata. Kroza me tko uđe, spasit će se: i ulazit će i izlaziti i pašu nalaziti."},{"v":10,"t":"Kradljivac dolazi samo da ukrade, zakolje i pogubi. Ja dođoh da život imaju, u izobilju da ga imaju.”"},{"v":11,"t":"“Ja sam pastir dobri. Pastir dobri život svoj polaže za ovce."},{"v":12,"t":"Najamnik - koji nije pastir i nije vlasnik ovaca - kad vidi vuka gdje dolazi, ostavlja ovce i bježi, a vuk ih grabi i razgoni:"},{"v":13,"t":"najamnik je i nije mu do ovaca."},{"v":14,"t":"Ja sam pastir dobri i poznajem svoje i mene poznaju moje,"},{"v":15,"t":"kao što mene poznaje Otac i ja poznajem Oca i život svoj polažem za ovce."},{"v":16,"t":"Imam i drugih ovaca, koje nisu iz ovog ovčinjaka. I njih treba da dovedem i glas će moj čuti i bit će jedno stado, jedan pastir."},{"v":17,"t":"Zbog toga me i ljubi Otac što polažem život svoj da ga opet uzmem."},{"v":18,"t":"Nitko mi ga ne oduzima, nego ja ga sam od sebe polažem. Vlast imam položiti ga, vlast imam opet uzeti ga. Tu zapovijed primih od Oca svoga.”"},{"v":19,"t":"Među Židovima ponovno nasta podvojenost zbog tih riječi."},{"v":20,"t":"Mnogi su od njih govorili: “Zloduha ima pa mahnita! Što ga slušate?”"},{"v":21,"t":"Drugi su govorili: “Nisu to riječi opsjednuta. Zar zloduh može slijepima oči otvoriti?”"},{"v":22,"t":"Svetkovao se tada u Jeruzalemu Blagdan posvećenja. Bila je zima."},{"v":23,"t":"Isus je obilazio Hramom po trijemu Salomonovu."},{"v":24,"t":"Okružili ga Židovi i govorili mu: “Dokle ćeš nam dušu držati u neizvjesnosti? Ako si ti Krist, reci nam otvoreno!”"},{"v":25,"t":"Isus im odgovori: “Rekoh vam pa ne vjerujete. Djela što ih ja činim u ime Oca svoga - ona svjedoče za mene."},{"v":26,"t":"Ali vi ne vjerujete jer niste od mojih ovaca."},{"v":27,"t":"Ovce moje slušaju glas moj; ja ih poznajem i one idu za mnom."},{"v":28,"t":"Ja im dajem život vječni te neće propasti nikada i nitko ih neće ugrabiti iz moje ruke."},{"v":29,"t":"Otac moj, koji mi ih dade, veći je od svih i nitko ih ne može ugrabiti iz ruke Očeve."},{"v":30,"t":"Ja i Otac jedno smo.”"},{"v":31,"t":"Židovi ponovno pograbiše kamenje da ga kamenuju."},{"v":32,"t":"Isus im odgovori: “Mnoga vam dobra djela Očeva pokazah. Za koje me od tih djela kamenujete?”"},{"v":33,"t":"Odgovoriše mu Židovi: “Zbog dobra te djela ne kamenujemo, nego zbog hule: što ti - čovjek - sebe Bogom praviš.”"},{"v":34,"t":"Odgovori im Isus: “Nije li pisano u vašem Zakonu: Ja rekoh: bogovi ste!"},{"v":35,"t":"Ako bogovima nazva one kojima je riječ Božja upravljena - a Pismo se ne može dokinuti -"},{"v":36,"t":"kako onda vi onome kog Otac posveti i posla na svijet možete reći: 'Huliš!' - zbog toga što rekoh: 'Sin sam Božji!'"},{"v":37,"t":"Ako ne činim djela Oca svoga, nemojte mi vjerovati."},{"v":38,"t":"Ali ako činim, sve ako meni i ne vjerujete, djelima vjerujte pa uvidite i upoznajte da je Otac u meni i ja u Ocu.”"},{"v":39,"t":"Nato ga ponovno nastojahu uhvatiti, ali im on izmaknu iz ruku."},{"v":40,"t":"I ode ponovno na onu stranu Jordana - na mjesto gdje je prije Ivan krstio. I osta ondje."},{"v":41,"t":"A mnogi dođoše k njemu i rekoše mu: “Ivan doduše ne učini nijednog znamenja, ali se sve obistinilo što je rekao o ovome.”"},{"v":42,"t":"Mnogi ondje povjerovaše u njega."}]},"11":{"fa":[{"v":1,"t":"و شخصی ایلعازر نام، بیمار بود، از اهل بیت عنیا که ده مریم و خواهرش مرتابود."},{"v":2,"t":"و مریم آن است که خداوند را به عطر، تدهین ساخت و پایهای او را به موی خودخشکانید که برادرش ایلعازر بیمار بود."},{"v":3,"t":"پس خواهرانش نزد او فرستاده، گفتند: «ای آقا، اینک آن که او را دوست می‌داری مریض است.»"},{"v":4,"t":"چون عیسی این را شنید گفت: «این مرض تا به موت نیست بلکه برای جلال خدا تا پسر خدا از آن جلال یابد.»"},{"v":5,"t":"و عیسی مرتا و خواهرش و ایلعازررا محبت می‌نمود."},{"v":6,"t":"پس چون شنید که بیمار است در جایی که بود دو روز توقف نمود."},{"v":7,"t":"و بعد از آن به شاگردان خود گفت: «باز به یهودیه برویم.»"},{"v":8,"t":"شاگردان او راگفتند: «ای معلم، الان یهودیان می‌خواستند تو راسنگسار کنند؛ و آیا باز می‌خواهی بدانجابروی؟»"},{"v":9,"t":"عیسی جواب داد: «آیا ساعتهای روزدوازده نیست؟ اگر کسی در روز راه رود لغزش نمی خورد زیرا که نور این جهان را می‌بیند."},{"v":10,"t":"ولیکن اگر کسی در شب راه رود لغزش خورد زیراکه نور در او نیست.»"},{"v":11,"t":"این را گفت و بعد از آن به ایشان فرمود: «دوست ما ایلعازر در خواب است. اما می‌روم تا او را بیدار کنم.»"},{"v":12,"t":"شاگردان اوگفتند: «ای آقا اگر خوابیده است، شفا خواهدیافت.»"},{"v":13,"t":"اما عیسی درباره موت او سخن گفت وایشان گمان بردند که از آرامی خواب می‌گوید."},{"v":14,"t":"آنگاه عیسی علانیه بدیشان گفت: «ایلعازرمرده است."},{"v":15,"t":"و برای شما خشنود هستم که درآنجا نبودم تا ایمان آرید ولکن نزد او برویم.»"},{"v":16,"t":"پس توما که به‌معنی توام باشد به همشاگردان خود گفت: «ما نیز برویم تا با او بمیریم.»"},{"v":17,"t":"پس چون عیسی آمد، یافت که چهار روزاست در قبر می‌باشد."},{"v":18,"t":"و بیت عنیا نزدیک اورشلیم بود، قریب به پانزده تیر پرتاب."},{"v":19,"t":"وبسیاری از یهود نزد مرتا و مریم آمده بودند تابجهت برادرشان، ایشان را تسلی دهند."},{"v":20,"t":"وچون مرتا شنید که عیسی می‌آید، او را استقبال کرد. لیکن مریم در خانه نشسته ماند."},{"v":21,"t":"پس مرتابه عیسی گفت: «ای آقا اگر در اینجا می‌بودی، برادر من نمی مرد."},{"v":22,"t":"ولیکن الان نیز می‌دانم که هرچه از خدا طلب کنی، خدا آن را به تو خواهد داد."},{"v":23,"t":"عیسی بدو گفت: «برادر تو خواهد برخاست.»"},{"v":24,"t":"مرتا به وی گفت: «می‌دانم که در قیامت روزبازپسین خواهد برخاست.»"},{"v":25,"t":"عیسی بدو گفت: «من قیامت و حیات هستم. هر‌که به من ایمان آورد، اگر مرده باشد، زنده گردد."},{"v":26,"t":"و هر‌که زنده بود و به من ایمان آورد، تا به ابد نخواهد مرد. آیااین را باور می‌کنی؟»"},{"v":27,"t":"او گفت: «بلی‌ای آقا، من ایمان دارم که تویی مسیح پسر خدا که در جهان آینده است.»"},{"v":28,"t":"و چون این را گفت، رفت و خواهر خودمریم را در پنهانی خوانده، گفت: «استاد آمده است و تو را می‌خواند.»"},{"v":29,"t":"او چون این را بشنید، بزودی برخاسته، نزد او آمد."},{"v":30,"t":"و عیسی هنوزوارد ده نشده بود، بلکه در جایی بود که مرتا او راملاقات کرد."},{"v":31,"t":"و یهودیانی که در خانه با او بودندو او را تسلی می‌دادند، چون دیدند که مریم برخاسته، به تعجیل بیرون می‌رود، از عقب اوآمده، گفتند: «به‌سر قبر می‌رود تا در آنجا گریه کند.»"},{"v":32,"t":"و مریم چون به‌جایی که عیسی بودرسید، او را دیده، بر قدمهای او افتاد و بدو گفت: «ای آقا اگر در اینجا می‌بودی، برادر من نمی مرد.»"},{"v":33,"t":"عیسی چون او را گریان دید و یهودیان را هم که با او آمده بودند گریان یافت، در روح خودبشدت مکدر شده، مضطرب گشت."},{"v":34,"t":"و گفت: «او را کجا گذارده‌اید؟» به او گفتند: «ای آقا بیا وببین.»"},{"v":35,"t":"عیسی بگریست."},{"v":36,"t":"آنگاه یهودیان گفتند: «بنگرید چقدر او را دوست می‌داشت!»"},{"v":37,"t":"بعضی از ایشان گفتند: «آیا این شخص که چشمان کور را باز کرد، نتوانست امر کند که این مرد نیز نمیرد؟»"},{"v":38,"t":"پس عیسی باز بشدت در خود مکدر شده، نزد قبر‌آمد و آن غاره‌ای بود، سنگی بر سرش گذارده."},{"v":39,"t":"عیسی گفت: «سنگ را بردارید.» مرتاخواهر میت بدو گفت: «ای آقا الان متعفن شده، زیرا که چهار روز گذشته است.»"},{"v":40,"t":"عیسی به وی گفت: «آیا به تو نگفتم اگر ایمان بیاوری، جلال خدا را خواهی دید؟»"},{"v":41,"t":"پس سنگ را از جایی که میت گذاشته شده بود برداشتند. عیسی چشمان خود را بالا انداخته، گفت: «ای پدر، تو را شکرمی کنم که سخن مرا شنیدی."},{"v":42,"t":"و من می‌دانستم که همیشه سخن مرا می‌شنوی؛ و لکن بجهت خاطر این گروه که حاضرند گفتم تا ایمان بیاورندکه تو مرا فرستادی.»"},{"v":43,"t":"چون این را گفت، به آوازبلند ندا کرد: «ای ایلعازر، بیرون بیا.»"},{"v":44,"t":"در حال آن مرده دست و پای به کفن بسته بیرون آمد وروی او به‌دستمالی پیچیده بود. عیسی بدیشان گفت: «او را باز کنید و بگذارید برود.»"},{"v":45,"t":"آنگاه بسیاری از یهودیان که با مریم آمده بودند، چون آنچه عیسی کرد دیدند، بدو ایمان آوردند."},{"v":46,"t":"ولیکن بعضی از ایشان نزد فریسیان رفتند و ایشان را از کارهایی که عیسی کرده بودآگاه ساختند."},{"v":47,"t":"پس روسای کهنه و فریسیان شورا نموده، گفتند: «چه کنیم زیرا که این مرد، معجزات بسیارمی نماید؟"},{"v":48,"t":"اگر او را چنین واگذاریم، همه به اوایمان خواهند‌آورد و رومیان آمده، جا و قوم مارا خواهند گرفت.»"},{"v":49,"t":"یکی از ایشان، قیافا نام که در آن سال رئیس کهنه بود، بدیشان گفت: «شماهیچ نمی دانید"},{"v":50,"t":"و فکر نمی کنید که بجهت مامفید است که یک شخص در راه قوم بمیرد وتمامی طائفه هلاک نگردند.»"},{"v":51,"t":"و این را از خودنگفت بلکه چون در آن سال رئیس کهنه بود، نبوت کرد که می‌بایست عیسی در راه آن طایفه بمیرد؛"},{"v":52,"t":"و نه در راه آن طایفه تنها بلکه تا فرزندان خدا را که متفرقند در یکی جمع کند."},{"v":53,"t":"و از همان روز شورا کردند که او را بکشند."},{"v":54,"t":"پس بعداز آن عیسی در میان یهود آشکارا راه نمی رفت بلکه از آنجا روانه شد به موضعی نزدیک بیابان به شهری که افرایم نام داشت و با شاگردان خود درآنجا توقف نمود."},{"v":55,"t":"و چون فصح یهود نزدیک شد، بسیاری ازبلوکات قبل از فصح به اورشلیم آمدند تا خود راطاهر سازند"},{"v":56,"t":"و در طلب عیسی می‌بودند و درهیکل ایستاده، به یکدیگر می‌گفتند: « «چه گمان می‌برید؟ آیا برای عید نمی آید؟»"},{"v":57,"t":"اما روسای کهنه و فریسیان حکم کرده بودند که اگر کسی بداند که کجا است اطلاع دهد تا او را گرفتارسازند."}],"en":[{"v":1,"t":"Now a certain man was sick, Lazarus from Bethany, of the village of Mary and her sister, Martha."},{"v":2,"t":"It was that Mary who had anointed the Lord with ointment and wiped his feet with her hair, whose brother Lazarus was sick."},{"v":3,"t":"The sisters therefore sent to him, saying, “Lord, behold, he for whom you have great affection is sick.”"},{"v":4,"t":"But when Jesus heard it, he said, “This sickness is not to death, but for the glory of God, that God’s Son may be glorified by it.”"},{"v":5,"t":"Now Jesus loved Martha, and her sister, and Lazarus."},{"v":6,"t":"When therefore he heard that he was sick, he stayed two days in the place where he was."},{"v":7,"t":"Then after this he said to the disciples, “Let’s go into Judea again.”"},{"v":8,"t":"The disciples asked him, “Rabbi, the Jews were just trying to stone you. Are you going there again?”"},{"v":9,"t":"Jesus answered, “Aren’t there twelve hours of daylight? If a man walks in the day, he doesn’t stumble, because he sees the light of this world."},{"v":10,"t":"But if a man walks in the night, he stumbles, because the light isn’t in him.”"},{"v":11,"t":"He said these things, and after that, he said to them, “Our friend Lazarus has fallen asleep, but I am going so that I may awake him out of sleep.”"},{"v":12,"t":"The disciples therefore said, “Lord, if he has fallen asleep, he will recover.”"},{"v":13,"t":"Now Jesus had spoken of his death, but they thought that he spoke of taking rest in sleep."},{"v":14,"t":"So Jesus said to them plainly then, “Lazarus is dead."},{"v":15,"t":"I am glad for your sakes that I was not there, so that you may believe. Nevertheless, let’s go to him.”"},{"v":16,"t":"Thomas therefore, who is called Didymus, said to his fellow disciples, “Let’s also go, that we may die with him.”"},{"v":17,"t":"So when Jesus came, he found that he had been in the tomb four days already."},{"v":18,"t":"Now Bethany was near Jerusalem, about fifteen stadia away."},{"v":19,"t":"Many of the Jews had joined the women around Martha and Mary, to console them concerning their brother."},{"v":20,"t":"Then when Martha heard that Jesus was coming, she went and met him, but Mary stayed in the house."},{"v":21,"t":"Therefore Martha said to Jesus, “Lord, if you would have been here, my brother wouldn’t have died."},{"v":22,"t":"Even now I know that whatever you ask of God, God will give you.”"},{"v":23,"t":"Jesus said to her, “Your brother will rise again.”"},{"v":24,"t":"Martha said to him, “I know that he will rise again in the resurrection at the last day.”"},{"v":25,"t":"Jesus said to her, “I am the resurrection and the life. He who believes in me will still live, even if he dies."},{"v":26,"t":"Whoever lives and believes in me will never die. Do you believe this?”"},{"v":27,"t":"She said to him, “Yes, Lord. I have come to believe that you are the Christ, God’s Son, he who comes into the world.”"},{"v":28,"t":"When she had said this, she went away and called Mary, her sister, secretly, saying, “The Teacher is here and is calling you.”"},{"v":29,"t":"When she heard this, she arose quickly and went to him."},{"v":30,"t":"Now Jesus had not yet come into the village, but was in the place where Martha met him."},{"v":31,"t":"Then the Jews who were with her in the house and were consoling her, when they saw Mary, that she rose up quickly and went out, followed her, saying, “She is going to the tomb to weep there.”"},{"v":32,"t":"Therefore when Mary came to where Jesus was and saw him, she fell down at his feet, saying to him, “Lord, if you would have been here, my brother wouldn’t have died.”"},{"v":33,"t":"When Jesus therefore saw her weeping, and the Jews weeping who came with her, he groaned in the spirit and was troubled,"},{"v":34,"t":"and said, “Where have you laid him?” They told him, “Lord, come and see.”"},{"v":35,"t":"Jesus wept."},{"v":36,"t":"The Jews therefore said, “See how much affection he had for him!”"},{"v":37,"t":"Some of them said, “Couldn’t this man, who opened the eyes of him who was blind, have also kept this man from dying?”"},{"v":38,"t":"Jesus therefore, again groaning in himself, came to the tomb. Now it was a cave, and a stone lay against it."},{"v":39,"t":"Jesus said, “Take away the stone.” Martha, the sister of him who was dead, said to him, “Lord, by this time there is a stench, for he has been dead four days.”"},{"v":40,"t":"Jesus said to her, “Didn’t I tell you that if you believed, you would see God’s glory?”"},{"v":41,"t":"So they took away the stone from the place where the dead man was lying. Jesus lifted up his eyes and said, “Father, I thank you that you listened to me."},{"v":42,"t":"I know that you always listen to me, but because of the multitude standing around I said this, that they may believe that you sent me.”"},{"v":43,"t":"When he had said this, he cried with a loud voice, “Lazarus, come out!”"},{"v":44,"t":"He who was dead came out, bound hand and foot with wrappings, and his face was wrapped around with a cloth. Jesus said to them, “Free him, and let him go.”"},{"v":45,"t":"Therefore many of the Jews who came to Mary and saw what Jesus did believed in him."},{"v":46,"t":"But some of them went away to the Pharisees and told them the things which Jesus had done."},{"v":47,"t":"The chief priests therefore and the Pharisees gathered a council, and said, “What are we doing? For this man does many signs."},{"v":48,"t":"If we leave him alone like this, everyone will believe in him, and the Romans will come and take away both our place and our nation.”"},{"v":49,"t":"But a certain one of them, Caiaphas, being high priest that year, said to them, “You know nothing at all,"},{"v":50,"t":"nor do you consider that it is advantageous for us that one man should die for the people, and that the whole nation not perish.”"},{"v":51,"t":"Now he didn’t say this of himself, but being high priest that year, he prophesied that Jesus would die for the nation,"},{"v":52,"t":"and not for the nation only, but that he might also gather together into one the children of God who are scattered abroad."},{"v":53,"t":"So from that day forward they took counsel that they might put him to death."},{"v":54,"t":"Jesus therefore walked no more openly among the Jews, but departed from there into the country near the wilderness, to a city called Ephraim. He stayed there with his disciples."},{"v":55,"t":"Now the Passover of the Jews was at hand. Many went up from the country to Jerusalem before the Passover, to purify themselves."},{"v":56,"t":"Then they sought for Jesus and spoke with one another as they stood in the temple, “What do you think—that he isn’t coming to the feast at all?”"},{"v":57,"t":"Now the chief priests and the Pharisees had commanded that if anyone knew where he was, he should report it, that they might seize him."}],"hr":[{"v":1,"t":"Bijaše neki bolesnik, Lazar iz Betanije, iz sela Marije i sestre joj Marte."},{"v":2,"t":"Marija bijaše ono pomazala Gospodina pomašću i otrla mu noge svojom kosom. Njezin dakle brat Lazar bijaše bolestan."},{"v":3,"t":"Sestre stoga poručiše Isusu: “Gospodine, evo onaj koga ljubiš, bolestan je.”"},{"v":4,"t":"Čuvši to, Isus reče: “Ta bolest nije na smrt, nego na slavu Božju, da se po njoj proslavi Sin Božji.”"},{"v":5,"t":"A Isus ljubljaše Martu i njezinu sestru i Lazara."},{"v":6,"t":"Ipak, kad je čuo za njegovu bolest, ostade još dva dana u onome mjestu gdje se nalazio."},{"v":7,"t":"Istom nakon toga reče učenicima: “Pođimo opet u Judeju!”"},{"v":8,"t":"Kažu mu učenici: “Učitelju, Židovi su sad tražili da te kamenuju, pa da opet ideš onamo?”"},{"v":9,"t":"Odgovori Isus: “Nema li dan dvanaest sati? Hodi li tko danju, ne spotiče se jer vidi svjetlost ovoga svijeta."},{"v":10,"t":"Hodi li tko noću, spotiče se jer nema svjetlosti u njemu.”"},{"v":11,"t":"To reče, a onda im dometnu: “Lazar, prijatelj naš, spava, no idem probuditi ga.”"},{"v":12,"t":"Rekoše mu nato učenici: “Gospodine, ako spava, ozdravit će.”"},{"v":13,"t":"No Isus to reče o njegovoj smrti, a oni pomisliše da govori o spavanju, o snu."},{"v":14,"t":"Tada im Isus reče posve otvoreno: “Lazar je umro."},{"v":15,"t":"Ja se radujem što ne bijah ondje, i to poradi vas - da uzvjerujete. Nego pođimo k njemu!”"},{"v":16,"t":"Nato Toma zvani Blizanac reče suučenicima: “Hajdemo i mi da umremo s njime!”"},{"v":17,"t":"Kad je dakle Isus stigao, nađe da je onaj već četiri dana u grobu."},{"v":18,"t":"Betanija bijaše blizu Jeruzalema otprilike petnaest stadija."},{"v":19,"t":"A mnogo Židova bijaše došlo tješiti Martu i Mariju zbog brata njihova."},{"v":20,"t":"Kad Marta doču da Isus dolazi, pođe mu u susret dok je Marija ostala u kući."},{"v":21,"t":"Marta reče Isusu: “Gospodine, da si bio ovdje, brat moj ne bi umro."},{"v":22,"t":"Ali i sada znam: što god zaišteš od Boga, dat će ti.”"},{"v":23,"t":"Kaza joj Isus: “Uskrsnut će brat tvoj!”"},{"v":24,"t":"A Marta mu odgovori: “Znam da će uskrsnuti o uskrsnuću, u posljednji dan.”"},{"v":25,"t":"Reče joj Isus: “Ja sam uskrsnuće i život: tko u mene vjeruje, ako i umre, živjet će."},{"v":26,"t":"I tko god živi i vjeruje u mene, neće umrijeti nikada. Vjeruješ li ovo?”"},{"v":27,"t":"Odgovori mu: “Da, Gospodine! Ja vjerujem da si ti Krist, Sin Božji, Onaj koji dolazi na svijet!”"},{"v":28,"t":"Rekavši to ode, zovnu svoju sestru Mariju i reče joj krišom: “Učitelj je ovdje i zove te.”"},{"v":29,"t":"A ona, čim doču, brzo ustane i pođe k njemu."},{"v":30,"t":"Isus još ne bijaše ušao u selo, nego je dotada bio na mjestu gdje ga je Marta susrela."},{"v":31,"t":"Kad Židovi, koji su s Marijom bili u kući i tješili je, vidješe kako je brzo ustala i izišla, pođoše za njom; mišljahu da ide na grob plakati."},{"v":32,"t":"A kad Marija dođe onamo gdje bijaše Isus i kad ga ugleda, baci mu se k nogama govoreći: “Gospodine, da si bio ovjde, brat moj ne bi umro.”"},{"v":33,"t":"Kad Isus vidje kako plače ona i Židovi koji je dopratiše, potresen u duhu i uzbuđen"},{"v":34,"t":"upita: “Kamo ste ga položili?” Odgovoriše mu: “Gospodine, dođi i pogledaj!”"},{"v":35,"t":"I zaplaka Isus."},{"v":36,"t":"Nato su Židovi govorili: “Gle, kako ga je ljubio!”"},{"v":37,"t":"A neki između njih rekoše: “Zar on, koji je slijepcu otvorio oči, nije mogao učiniti da ovaj ne umre?”"},{"v":38,"t":"Isus onda, ponovno potresen, pođe grobu. Bila je to pećina, a na nju navaljen kamen."},{"v":39,"t":"Isus zapovjedi: “Odvalite kamen!” Kaže mu pokojnikova sestra Marta: “Gospodine, već zaudara. Ta četvrti je dan.”"},{"v":40,"t":"Kaže joj Isus: “Nisam li ti rekao: budeš li vjerovala, vidjet ćeš slavu Božju?”"},{"v":41,"t":"Odvališe dakle kamen. A Isus podiže oči i reče: “Oče, hvala ti što si me uslišao."},{"v":42,"t":"Ja sam znao da me svagda uslišavaš; no rekoh to zbog nazočnog mnoštva: da vjeruju da si me ti poslao.”"},{"v":43,"t":"Rekavši to povika iza glasa: “Lazare, izlazi!”"},{"v":44,"t":"I mrtvac iziđe, noge mu i ruke bile povezane povojima, a lice omotano ručnikom. Nato Isus reče: “Odriješite ga i pustite neka ide!”"},{"v":45,"t":"Tada mnogi Židovi koji bijahu došli k Mariji, kad vidješe što Isus učini, povjerovaše u nj."},{"v":46,"t":"A neki od njih odu farizejima i pripovjede im što Isus učini."},{"v":47,"t":"Stoga glavari svećenički i farizeji sazvaše Vijeće. Govorili su: “Što da radimo? Ovaj čovjek čini mnoga znamenja."},{"v":48,"t":"Ako ga pustimo tako, svi će povjerovati u nj pa će doći Rimljani i oduzeti nam ovo mjesto i narod!”"},{"v":49,"t":"A jedan od njih - Kajfa, veliki svećenik one godine - reče im: “Vi ništa ne znate."},{"v":50,"t":"I ne mislite kako je za vas bolje da jedan čovjek umre za narod, nego da sav narod propadne!”"},{"v":51,"t":"To ne reče sam od sebe, nego kao veliki svećenik one godine prorokova da Isus ima umrijeti za narod;"},{"v":52,"t":"ali ne samo za narod nego i zato da raspršene sinove Božje skupi u jedno."},{"v":53,"t":"Toga dana dakle odluče da ga ubiju."},{"v":54,"t":"Zbog toga se Isus više nije javno kretao među Židovima, nego je odatle otišao u kraj blizu pustinje, u grad koji se zove Efrajim. Tu se zadržavao s učenicima."},{"v":55,"t":"Bijaše blizu židovska Pasha i mnogi iz toga kraja uziđoše prije Pashe u Jeruzalem da se očiste."},{"v":56,"t":"Iskahu dakle Isusa te se stojeći u Hramu zapitkivahu: “Što vam se čini? Zar on ne kani doći na Blagdan?”"},{"v":57,"t":"A glavari svećenički i farizeji izdadoše naredbu: ako tko sazna gdje je, neka dojavi da ga uhvate."}]},"12":{"fa":[{"v":1,"t":"پس شش روز قبل از عید فصح، عیسی به بیت عنیا آمد، جایی که ایلعازر مرده را از مردگان برخیزانیده بود."},{"v":2,"t":"و برای او در آنجاشام حاضر کردند و مرتا خدمت می‌کرد و ایلعازریکی از مجلسیان با او بود."},{"v":3,"t":"آنگاه مریم رطلی ازعطر سنبل خالص گرانبها گرفته، پایهای عیسی راتدهین کرد و پایهای او را از مویهای خودخشکانید، چنانکه خانه از بوی عطر پر شد."},{"v":4,"t":"پس یکی از شاگردان او یعنی یهودای اسخریوطی، پسر شمعون که تسلیم‌کننده وی بود، گفت:"},{"v":5,"t":"«برای چه این عطر به سیصد دینار فروخته نشدتا به فقرا داده شود؟»"},{"v":6,"t":"و این را نه از آنرو گفت که پروای فقرا می‌داشت، بلکه از آنرو که دزد بود وخریطه در حواله او و از آنچه در آن انداخته می‌شد برمی داشت."},{"v":7,"t":"عیسی گفت: «او را واگذارزیرا که بجهت روز تکفین من این را نگاه داشته است."},{"v":8,"t":"زیرا که فقرا همیشه با شما می‌باشند و امامن همه وقت با شما نیستم.»"},{"v":9,"t":"پس جمعی کثیر از یهود چون دانستند که عیسی در آنجا است آمدند نه برای عیسی و بس بلکه تا ایلعازر را نیز که از مردگانش برخیزانیده بود ببینند."},{"v":10,"t":"آنگاه روسای کهنه شورا کردند که ایلعازر را نیز بکشند."},{"v":11,"t":"زیرا که بسیاری از یهودبه‌سبب او می‌رفتند و به عیسی ایمان می‌آوردند."},{"v":12,"t":"فردای آن روز چون گروه بسیاری که برای عید آمده بودند شنیدند که عیسی به اورشلیم می‌آید،"},{"v":13,"t":"شاخه های نخل را گرفته به استقبال اوبیرون آمدند و ندا می‌کردند هوشیعانا مبارک بادپادشاه اسرائیل که به اسم خداوند می‌آید."},{"v":14,"t":"وعیسی کره الاغی یافته، بر آن سوار شد چنانکه مکتوب است"},{"v":15,"t":"که «ای دختر صهیون مترس، اینک پادشاه تو سوار بر کره الاغی می‌آید.»"},{"v":16,"t":"و شاگردانش اولا این چیزها رانفهمیدند، لکن چون عیسی جلال یافت، آنگاه به‌خاطر آوردند که این چیزها درباره او مکتوب است و همچنان با او کرده بودند."},{"v":17,"t":"و گروهی که با او بودند شهادت دادند که ایلعازر را از قبرخوانده، او را از مردگان برخیزانیده است."},{"v":18,"t":"وبجهت همین نیز آن گروه او را استقبال کردند، زیرا شنیده بودند که آن معجزه را نموده بود."},{"v":19,"t":"پس فریسیان به یکدیگر گفتند: «نمی بینید که هیچ نفع نمی برید؟ اینک تمام عالم از پی او رفته‌اند!»"},{"v":20,"t":"و از آن کسانی که در عید بجهت عبادت آمده بودند، بعضی یونانی بودند."},{"v":21,"t":"ایشان نزدفیلپس که از بیت صیدای جلیل بود آمدند و سوال کرده، گفتند: «ای آقا می‌خواهیم عیسی را ببینیم.»"},{"v":22,"t":"فیلپس آمد و به اندریاس گفت و اندریاس وفیلپس به عیسی گفتند."},{"v":23,"t":"عیسی در جواب ایشان گفت: «ساعتی رسیده است که پسر انسان جلال یابد."},{"v":24,"t":"آمین آمین به شما می‌گویم اگر دانه گندم که در زمین می‌افتد نمیرد، تنها ماند لیکن اگربمیرد ثمر بسیار آورد."},{"v":25,"t":"کسی‌که جان خود رادوست دارد آن را هلاک کند و هر‌که در این جهان جان خود را دشمن دارد تا حیات جاودانی آن رانگاه خواهد داشت."},{"v":26,"t":"اگر کسی مرا خدمت کند، مرا پیروی بکند و جایی که من می‌باشم آنجاخادم من نیز خواهد بود؛ و هر‌که مرا خدمت کندپدر او را حرمت خواهد داشت."},{"v":27,"t":"الان جان من مضطرب است و چه بگویم؟ ای پدر مرا از این ساعت رستگار کن. لکن بجهت همین امر تا این ساعت رسیده‌ام."},{"v":28,"t":"‌ای پدر اسم خود را جلال بده!» ناگاه صدایی از آسمان در‌رسید که جلال دادم و باز جلال خواهم داد."},{"v":29,"t":"پس گروهی که حاضر بودند این را شنیده، گفتند: «رعد شد!» ودیگران گفتند: «فرشته‌ای با او تکلم کرد!»"},{"v":30,"t":"عیسی در جواب گفت: «این صدا از برای من نیامد، بلکه بجهت شما."},{"v":31,"t":"الحال داوری این جهان است و الان رئیس این جهان بیرون افکنده می‌شود."},{"v":32,"t":"و من اگر از زمین بلند کرده شوم، همه را به سوی خود خواهم کشید.»"},{"v":33,"t":"و این را گفت کنایه از آن قسم موت که می‌بایست بمیرد."},{"v":34,"t":"پس همه به او جواب دادند: «ما از تورات شنیده‌ایم که مسیح تا به ابد باقی می‌ماند. پس چگونه تو می‌گویی که پسر انسان باید بالا کشیده شود؟ کیست این پسر انسان؟»"},{"v":35,"t":"آنگاه عیسی بدیشان گفت: «اندک زمانی نور با شماست. پس مادامی که نور با شماست، راه بروید تا ظلمت شما را فرو نگیرد؛ و کسی‌که در تاریکی راه می‌رود نمی داند به کجا می‌رود."},{"v":36,"t":"مادامی که نوربا شماست به نور ایمان آورید تا پسران نورگردید.» عیسی چون این را بگفت، رفته خود را ازایشان مخفی ساخت."},{"v":37,"t":"و با اینکه پیش روی ایشان چنین معجزات بسیار نموده بود، بدو ایمان نیاوردند."},{"v":38,"t":"تا کلامی که اشعیا نبی گفت به اتمام رسد: «ای خداوندکیست که خبر ما را باور کرد و بازوی خداوند به که آشکار گردید؟»"},{"v":39,"t":"و از آنجهت نتوانستندایمان آورد، زیرا که اشعیا نیز گفت:"},{"v":40,"t":"«چشمان ایشان را کور کرد و دلهای ایشان را سخت ساخت تا به چشمان خود نبینند و به دلهای خود نفهمندو برنگردند تا ایشان را شفا دهم.»"},{"v":41,"t":"این کلام رااشعیا گفت وقتی که جلال او را دید و درباره اوتکلم کرد."},{"v":42,"t":"لکن با وجود این، بسیاری ازسرداران نیز بدو ایمان آوردند، اما به‌سبب فریسیان اقرار نکردند که مبادا از کنیسه بیرون شوند."},{"v":43,"t":"زیرا که جلال خلق را بیشتر از جلال خدا دوست می‌داشتند."},{"v":44,"t":"آنگاه عیسی ندا کرده، گفت: «آنکه به من ایمان آورد، نه به من بلکه به آنکه مرا فرستاده است، ایمان آورده است."},{"v":45,"t":"و کسی‌که مرا دید فرستنده مرا دیده است."},{"v":46,"t":"من نوری در جهان آمدم تا هر‌که به من ایمان آورد در ظلمت نماند."},{"v":47,"t":"و اگر کسی کلام مرا شنید و ایمان نیاورد، من براو داوری نمی کنم زیرا که نیامده‌ام تا جهان راداوری کنم بلکه تا جهان را نجات‌بخشم."},{"v":48,"t":"هرکه مرا حقیر شمارد و کلام مرا قبول نکند، کسی هست که در حق او داوری کند، همان کلامی که گفتم در روز بازپسین بر او داوری خواهد کرد."},{"v":49,"t":"زآنرو که من از خود نگفتم، لکن پدری که مرافرستاد، به من فرمان داد که چه بگویم و به چه چیزتکلم کنم."},{"v":50,"t":"و می‌دانم که فرمان او حیات جاودانی است. پس آنچه من می‌گویم چنانکه پدربمن گفته است، تکلم می‌کنم.»"}],"en":[{"v":1,"t":"Then, six days before the Passover, Jesus came to Bethany, where Lazarus was, who had been dead, whom he raised from the dead."},{"v":2,"t":"So they made him a supper there. Martha served, but Lazarus was one of those who sat at the table with him."},{"v":3,"t":"Therefore Mary took a pound of ointment of pure nard, very precious, and anointed Jesus’ feet and wiped his feet with her hair. The house was filled with the fragrance of the ointment."},{"v":4,"t":"Then Judas Iscariot, Simon’s son, one of his disciples, who would betray him, said,"},{"v":5,"t":"“Why wasn’t this ointment sold for three hundred denarii and given to the poor?”"},{"v":6,"t":"Now he said this, not because he cared for the poor, but because he was a thief, and having the money box, used to steal what was put into it."},{"v":7,"t":"But Jesus said, “Leave her alone. She has kept this for the day of my burial."},{"v":8,"t":"For you always have the poor with you, but you don’t always have me.”"},{"v":9,"t":"A large crowd therefore of the Jews learned that he was there; and they came, not for Jesus’ sake only, but that they might see Lazarus also, whom he had raised from the dead."},{"v":10,"t":"But the chief priests conspired to put Lazarus to death also,"},{"v":11,"t":"because on account of him many of the Jews went away and believed in Jesus."},{"v":12,"t":"On the next day a great multitude had come to the feast. When they heard that Jesus was coming to Jerusalem,"},{"v":13,"t":"they took the branches of the palm trees and went out to meet him, and cried out, “Hosanna! Blessed is he who comes in the name of the Lord, the King of Israel!”"},{"v":14,"t":"Jesus, having found a young donkey, sat on it. As it is written,"},{"v":15,"t":"“Don’t be afraid, daughter of Zion. Behold, your King comes, sitting on a donkey’s colt.”"},{"v":16,"t":"His disciples didn’t understand these things at first, but when Jesus was glorified, then they remembered that these things were written about him, and that they had done these things to him."},{"v":17,"t":"The multitude therefore that was with him when he called Lazarus out of the tomb and raised him from the dead was testifying about it."},{"v":18,"t":"For this cause also the multitude went and met him, because they heard that he had done this sign."},{"v":19,"t":"The Pharisees therefore said among themselves, “See how you accomplish nothing. Behold, the world has gone after him.”"},{"v":20,"t":"Now there were certain Greeks among those who went up to worship at the feast."},{"v":21,"t":"Therefore, these came to Philip, who was from Bethsaida of Galilee, and asked him, saying, “Sir, we want to see Jesus.”"},{"v":22,"t":"Philip came and told Andrew, and in turn, Andrew came with Philip, and they told Jesus."},{"v":23,"t":"Jesus answered them, “The time has come for the Son of Man to be glorified."},{"v":24,"t":"Most certainly I tell you, unless a grain of wheat falls into the earth and dies, it remains by itself alone. But if it dies, it bears much fruit."},{"v":25,"t":"He who loves his life will lose it. He who hates his life in this world will keep it to eternal life."},{"v":26,"t":"If anyone serves me, let him follow me. Where I am, there my servant will also be. If anyone serves me, the Father will honor him."},{"v":27,"t":"“Now my soul is troubled. What shall I say? ‘Father, save me from this time’? But I came to this time for this cause."},{"v":28,"t":"Father, glorify your name!” Then a voice came out of the sky, saying, “I have both glorified it and will glorify it again.”"},{"v":29,"t":"Therefore the multitude who stood by and heard it said that it had thundered. Others said, “An angel has spoken to him.”"},{"v":30,"t":"Jesus answered, “This voice hasn’t come for my sake, but for your sakes."},{"v":31,"t":"Now is the judgment of this world. Now the prince of this world will be cast out."},{"v":32,"t":"And I, if I am lifted up from the earth, will draw all people to myself.”"},{"v":33,"t":"But he said this, signifying by what kind of death he should die."},{"v":34,"t":"The multitude answered him, “We have heard out of the law that the Christ remains forever. How do you say, ‘The Son of Man must be lifted up’? Who is this Son of Man?”"},{"v":35,"t":"Jesus therefore said to them, “Yet a little while the light is with you. Walk while you have the light, that darkness doesn’t overtake you. He who walks in the darkness doesn’t know where he is going."},{"v":36,"t":"While you have the light, believe in the light, that you may become children of light.” Jesus said these things, and he departed and hid himself from them."},{"v":37,"t":"But though he had done so many signs before them, yet they didn’t believe in him,"},{"v":38,"t":"that the word of Isaiah the prophet might be fulfilled, which he spoke: “Lord, who has believed our report? To whom has the arm of the Lord been revealed?”"},{"v":39,"t":"For this cause they couldn’t believe, for Isaiah said again:"},{"v":40,"t":"“He has blinded their eyes and he hardened their heart, lest they should see with their eyes, and perceive with their heart, and would turn, and I would heal them.”"},{"v":41,"t":"Isaiah said these things when he saw his glory, and spoke of him."},{"v":42,"t":"Nevertheless, even many of the rulers believed in him, but because of the Pharisees they didn’t confess it, so that they wouldn’t be put out of the synagogue,"},{"v":43,"t":"for they loved men’s praise more than God’s praise."},{"v":44,"t":"Jesus cried out and said, “Whoever believes in me, believes not in me, but in him who sent me."},{"v":45,"t":"He who sees me sees him who sent me."},{"v":46,"t":"I have come as a light into the world, that whoever believes in me may not remain in the darkness."},{"v":47,"t":"If anyone listens to my sayings and doesn’t believe, I don’t judge him. For I came not to judge the world, but to save the world."},{"v":48,"t":"He who rejects me, and doesn’t receive my sayings, has one who judges him. The word that I spoke will judge him in the last day."},{"v":49,"t":"For I spoke not from myself, but the Father who sent me gave me a commandment, what I should say and what I should speak."},{"v":50,"t":"I know that his commandment is eternal life. The things therefore which I speak, even as the Father has said to me, so I speak.”"}],"hr":[{"v":1,"t":"Šest dana prije Pashe dođe Isus u Betaniju gdje bijaše Lazar koga je Isus uskrisio od mrtvih."},{"v":2,"t":"Ondje mu prirediše večeru. Marta posluživaše, a Lazar bijaše jedan od njegovih sustolnika."},{"v":3,"t":"Tada Marija uzme libru prave dragocjene nardove pomasti, pomaže Isusu noge i otare ih svojom kosom. I sva se kuća napuni mirisom pomasti."},{"v":4,"t":"Nato reče Juda Iškariotski, jedan od njegovih učenika, onaj koji ga je imao izdati:"},{"v":5,"t":"“Zašto se ta pomast nije prodala za trista denara i razdala siromasima?”"},{"v":6,"t":"To ne reče zbog toga što mu bijaše stalo do siromaha, nego što bijaše kradljivac: kako je imao kesu, kradom je uzimao što se u nju stavljalo."},{"v":7,"t":"Nato Isus odvrati: “Pusti je! Neka to izvrši za dan mog ukopa!"},{"v":8,"t":"Jer siromahe imate uvijek uza se, a mene nemate uvijek.”"},{"v":9,"t":"Silno mnoštvo Židova dozna da je Isus ondje pa se okupi, ne samo zbog Isusa, već i zato da vide Lazara kojega on bijaše uskrisio od mrtvih."},{"v":10,"t":"A glavari svećenički odlučiše i Lazara ubiti"},{"v":11,"t":"jer su zbog njega mnogi Židovi odlazili i vjerovali u Isusa."},{"v":12,"t":"Kad je sutradan silan svijet koji dođe na Blagdan čuo da Isus dolazi u Jeruzalem,"},{"v":13,"t":"uze palmove grančice i iziđe mu u susret. Vikahu: “Hosana! Blagoslovljen Onaj koji dolazi u ime Gospodnje! Kralj Izraelov.”"},{"v":14,"t":"A Isus nađe magarčića i sjede na nj kao što je pisano:"},{"v":15,"t":"Ne boj se, kćeri Sionska! Evo, kralj tvoj dolazi jašuć na mladetu magaričinu!"},{"v":16,"t":"To učenici njegovi isprva ne razumješe. Ali pošto je Isus bio proslavljen, prisjetiše se da je to bilo o njemu napisano i da mu baš to učiniše."},{"v":17,"t":"Mnoštvo koje bijaše s njime kad Lazara pozva iz groba i uskrisi od mrtvih pronosilo je svjedočanstvo o tome."},{"v":18,"t":"Stoga mu je i izišao u susret silan svijet: pročulo se da je on učinio to znamenje."},{"v":19,"t":"Farizeji nato rekoše među sobom: “Vidite da ništa ne postižete. Eno, svijet ode za njim!”"},{"v":20,"t":"A među onima koji su se došli klanjati na Blagdan bijahu i neki Grci."},{"v":21,"t":"Oni pristupe Filipu iz Betsaide galilejske pa ga zamole: “Gospodine, htjeli bismo vidjeti Isusa.”"},{"v":22,"t":"Filip ode i kaže to Andriji pa Andrija i Filip odu i kažu Isusu."},{"v":23,"t":"Isus im odgovori: “Došao je čas da se proslavi Sin Čovječji."},{"v":24,"t":"Zaista, zaista, kažem vam: ako pšenično zrno, pavši na zemlju, ne umre, ostaje samo; ako li umre, donosi obilat rod."},{"v":25,"t":"Tko ljubi svoj život, izgubit će ga. A tko mrzi svoj život na ovome svijetu, sačuvat će ga za život vječni."},{"v":26,"t":"Ako mi tko hoće služiti, neka ide za mnom. I gdje sam ja, ondje će biti i moj služitelj. Ako mi tko hoće služiti, počastit će ga moj Otac.”"},{"v":27,"t":"“Duša mi je sada potresena i što da kažem? Oče, izbavi me iz ovoga časa? No, zato dođoh u ovaj čas!"},{"v":28,"t":"Oče, proslavi ime svoje!” Uto dođe glas s neba: “Proslavio sam i opet ću proslaviti!”"},{"v":29,"t":"Mnoštvo koje je ondje stajalo i slušalo govoraše: “Zagrmjelo je!” Drugi govorahu: “Anđeo mu je zborio.”"},{"v":30,"t":"Isus na to reče: “Ovaj glas nije bio poradi mene, nego poradi vas.”"},{"v":31,"t":"“Sada je sud ovomu svijetu, sada će knez ovoga svijeta biti izbačen."},{"v":32,"t":"A ja kad budem uzdignut sa zemlje, sve ću privući k sebi.”"},{"v":33,"t":"To reče da označi kakvom će smrću umrijeti."},{"v":34,"t":"Nato mu mnoštvo odgovori: “Mi smo iz Zakona čuli da Krist ostaje zauvijek. Kako onda ti govoriš da Sin Čovječji treba da bude uzdignut? Tko je taj Sin Čovječji?”"},{"v":35,"t":"Isus im nato reče: “Još je malo vremena svjetlost među vama. Hodite dok imate svjetlost da vas ne obuzme tama. Tko hodi u tami, ne zna kamo ide."},{"v":36,"t":"Dok imate svjetlost, vjerujte u svjetlost da budete sinovi svjetlosti!” To Isus doreče, a onda ode i sakri se od njih."},{"v":37,"t":"Iako je Isus pred njima učinio tolika znamenja, oni ne povjerovaše u njega,"},{"v":38,"t":"da se ispuni riječ koju kaza prorok Izaija: Gospodine! Tko povjerova našoj poruci? Kome li se otkri ruka Gospodnja?"},{"v":39,"t":"Stoga i ne mogahu vjerovati, jer Izaija dalje kaže:"},{"v":40,"t":"Zaslijepi im oči, stvrdnu srca; da očima ne vide, srcem ne razumiju te se ne obrate pa ih ozdravim."},{"v":41,"t":"Reče to Izaija jer je vidio slavu njegovu te o njemu zborio."},{"v":42,"t":"Ipak, mnogi su i od glavara vjerovali u njega, ali zbog farizeja nisu to priznavali: da ne budu izopćeni iz sinagoge."},{"v":43,"t":"Jer više im je bilo do slave ljudske, nego do slave Božje."},{"v":44,"t":"A Isus povika: “Tko u mene vjeruje, ne vjeruje u mene, nego u onoga koji me posla;"},{"v":45,"t":"i tko vidi mene, vidi onoga koji me posla."},{"v":46,"t":"Ja - Svjetlost - dođoh na svijet da nijedan koji u mene vjeruje u tami ne ostane."},{"v":47,"t":"I sluša li tko moje riječi, a ne čuva ih, ja ga ne sudim. Ja nisam došao suditi svijetu, nego svijet spasiti."},{"v":48,"t":"Tko mene odbacuje i riječi mojih ne prima, ima svoga suca: riječ koju sam zborio - ona će mu suditi u posljednji dan."},{"v":49,"t":"Jer nisam ja zborio sam od sebe, nego onaj koji me posla - Otac - on mi dade zapovijed što da kažem, što da zborim."},{"v":50,"t":"I znam: zapovijed njegova jest život vječni. Što ja dakle zborim, tako zborim kako mi je rekao Otac.”"}]},"13":{"fa":[{"v":1,"t":"و قبل از عید فصح، چون عیسی دانست که ساعت او رسیده است تا از این جهان به‌جانب پدر برود، خاصان خود را که در این جهان محبت می‌نمود، ایشان را تا به آخر محبت نمود."},{"v":2,"t":"و چون شام می‌خوردند و ابلیس پیش ازآن در دل یهودا پسر شمعون اسخریوطی نهاده بود که او را تسلیم کند،"},{"v":3,"t":"عیسی با اینکه می‌دانست که پدر همه‌چیز را به‌دست او داده است و از نزد خدا آمده و به‌جانب خدا می‌رود،"},{"v":4,"t":"از شام برخاست و جامه خود را بیرون کرد ودستمالی گرفته، به کمر بست."},{"v":5,"t":"پس آب در لگن ریخته، شروع کرد به شستن پایهای شاگردان وخشکانیدن آنها با دستمالی که بر کمر داشت."},{"v":6,"t":"پس چون به شمعون پطرس رسید، او به وی گفت: «ای آقا تو پایهای مرا می‌شویی؟»"},{"v":7,"t":"عیسی در جواب وی گفت: «آنچه من می‌کنم الان تونمی دانی، لکن بعد خواهی فهمید.»"},{"v":8,"t":"پطرس به اوگفت: «پایهای مرا هرگز نخواهی شست.» عیسی او را جواب داد: «اگر تو را نشویم تو را با من نصیبی نیست.»"},{"v":9,"t":"شمعون پطرس بدو گفت: «ای آقا نه پایهای مرا و بس، بلکه دستها و سر مرا نیز.»"},{"v":10,"t":"عیسی بدو گفت: «کسی‌که غسل یافت محتاج نیست مگر به شستن پایها، بلکه تمام او پاک است. و شما پاک هستید لکن نه همه.»"},{"v":11,"t":"زیرا که تسلیم‌کننده خود را می‌دانست و از این جهت گفت: «همگی شما پاک نیستید.»"},{"v":12,"t":"و چون پایهای ایشان را شست، رخت خودرا گرفته، باز بنشست و بدیشان گفت: «آیافهمیدید آنچه به شما کردم؟"},{"v":13,"t":"شما مرا استاد وآقا می‌خوانید و خوب می‌گویید زیرا که چنین هستم."},{"v":14,"t":"پس اگر من که آقا و معلم هستم، پایهای شما را شستم، بر شما نیز واجب است که پایهای یکدیگر را بشویید."},{"v":15,"t":"زیرا به شما نمونه‌ای دادم تا چنانکه من با شما کردم، شما نیز بکنید."},{"v":16,"t":"آمین آمین به شما می‌گویم غلام بزرگتر از آقای خودنیست و نه رسول از فرستنده خود."},{"v":17,"t":"هرگاه این را دانستید، خوشابحال شما اگر آن را به عمل آرید."},{"v":18,"t":"درباره جمیع شما نمی گویم؛ من آنانی راکه برگزیده‌ام می‌شناسم، لیکن تا کتاب تمام شود”آنکه با من نان می‌خورد، پاشنه خود را بر من بلندکرده است.”"},{"v":19,"t":"الان قبل از وقوع به شما می‌گویم تا زمانی که واقع شود باور کنید که من هستم."},{"v":20,"t":"آمین آمین به شما می‌گویم هر‌که قبول کندکسی را که می‌فرستم، مرا قبول کرده؛ و آنکه مرا قبول کند، فرستنده مرا قبول کرده باشد.»"},{"v":21,"t":"چون عیسی این را گفت، در روح مضطرب گشت و شهادت داده، گفت: «آمین آمین به شمامی گویم که یکی از شما مرا تسلیم خواهد کرد.»"},{"v":22,"t":"پس شاگردان به یکدیگر نگاه می‌کردند وحیران می‌بودند که این را درباره که می‌گوید."},{"v":23,"t":"ویکی از شاگردان او بود که به سینه عیسی تکیه می‌زد و عیسی او را محبت می‌نمود؛"},{"v":24,"t":"شمعون پطرس بدو اشاره کرد که بپرسد درباره که این راگفت."},{"v":25,"t":"پس او در آغوش عیسی افتاده، بدوگفت: «خداوندا کدام است؟»"},{"v":26,"t":"عیسی جواب داد: «آن است که من لقمه را فرو برده، بدومی دهم.» پس لقمه را فرو برده، به یهودای اسخریوطی پسر شمعون داد."},{"v":27,"t":"بعد از لقمه، شیطان در او داخل گشت. آنگاه عیسی وی راگفت، «آنچه می‌کنی، به زودی بکن.»"},{"v":28,"t":"اما این سخن را احدی از مجلسیان نفهمید که برای چه بدو گفت."},{"v":29,"t":"زیرا که بعضی گمان بردند که چون خریطه نزد یهودا بود، عیسی وی را فرمود تامایحتاج عید را بخرد یا آنکه چیزی به فقرا بدهد."},{"v":30,"t":"پس او لقمه را گرفته، در ساعت بیرون رفت و شب بود."},{"v":31,"t":"چون بیرون رفت عیسی گفت: «الان پسر انسان جلال یافت و خدا در او جلال یافت."},{"v":32,"t":"و اگر خدا در او جلال یافت، هرآینه خدا او را در خود جلال خواهد داد و به زودی اورا جلال خواهد داد."},{"v":33,"t":"‌ای فرزندان، اندک زمانی دیگر با شما هستم و مرا طلب خواهید کرد؛ وهمچنان‌که به یهود گفتم جایی که می‌روم شمانمی توانید آمد، الان نیز به شما می‌گویم."},{"v":34,"t":"به شما حکمی تازه می‌دهم که یکدیگر را محبت نمایید، چنانکه من شما را محبت نمودم تا شمانیز یکدیگر را محبت نمایید."},{"v":35,"t":"به همین همه خواهند فهمید که شاگرد من هستید اگر محبت یکدیگر را داشته باشید.»"},{"v":36,"t":"شمعون پطرس به وی گفت: «ای آقا کجا می‌روی؟» عیسی جواب داد: «جایی که می‌روم، الان نمی توانی از عقب من بیایی و لکن در آخر از عقب من خواهی آمد.»"},{"v":37,"t":"پطرس بدو گفت: «ای آقا برای چه الان نتوانم از عقب تو بیایم؟ جان خود را در راه تو خواهم نهاد.»"},{"v":38,"t":"عیسی به او جواب داد: «آیا جان خود رادر راه من می‌نهی؟ آمین آمین به تو می‌گویم تا سه مرتبه مرا انکار نکرده باشی، خروس بانگ نخواهد زد."}],"en":[{"v":1,"t":"Now before the feast of the Passover, Jesus, knowing that his time had come that he would depart from this world to the Father, having loved his own who were in the world, he loved them to the end."},{"v":2,"t":"During supper, the devil having already put into the heart of Judas Iscariot, Simon’s son, to betray him,"},{"v":3,"t":"Jesus, knowing that the Father had given all things into his hands, and that he came from God and was going to God,"},{"v":4,"t":"arose from supper, and laid aside his outer garments. He took a towel and wrapped a towel around his waist."},{"v":5,"t":"Then he poured water into the basin, and began to wash the disciples’ feet and to wipe them with the towel that was wrapped around him."},{"v":6,"t":"Then he came to Simon Peter. He said to him, “Lord, do you wash my feet?”"},{"v":7,"t":"Jesus answered him, “You don’t know what I am doing now, but you will understand later.”"},{"v":8,"t":"Peter said to him, “You will never wash my feet!” Jesus answered him, “If I don’t wash you, you have no part with me.”"},{"v":9,"t":"Simon Peter said to him, “Lord, not my feet only, but also my hands and my head!”"},{"v":10,"t":"Jesus said to him, “Someone who has bathed only needs to have his feet washed, but is completely clean. You are clean, but not all of you.”"},{"v":11,"t":"For he knew him who would betray him; therefore he said, “You are not all clean.”"},{"v":12,"t":"So when he had washed their feet, put his outer garment back on, and sat down again, he said to them, “Do you know what I have done to you?"},{"v":13,"t":"You call me, ‘Teacher’ and ‘Lord.’ You say so correctly, for so I am."},{"v":14,"t":"If I then, the Lord and the Teacher, have washed your feet, you also ought to wash one another’s feet."},{"v":15,"t":"For I have given you an example, that you should also do as I have done to you."},{"v":16,"t":"Most certainly I tell you, a servant is not greater than his lord, neither is one who is sent greater than he who sent him."},{"v":17,"t":"If you know these things, blessed are you if you do them."},{"v":18,"t":"I don’t speak concerning all of you. I know whom I have chosen; but that the Scripture may be fulfilled, ‘He who eats bread with me has lifted up his heel against me.’"},{"v":19,"t":"From now on, I tell you before it happens, that when it happens, you may believe that I am he."},{"v":20,"t":"Most certainly I tell you, he who receives whomever I send, receives me; and he who receives me, receives him who sent me.”"},{"v":21,"t":"When Jesus had said this, he was troubled in spirit, and testified, “Most certainly I tell you that one of you will betray me.”"},{"v":22,"t":"The disciples looked at one another, perplexed about whom he spoke."},{"v":23,"t":"One of his disciples, whom Jesus loved, was at the table, leaning against Jesus’ chest."},{"v":24,"t":"Simon Peter therefore beckoned to him, and said to him, “Tell us who it is of whom he speaks.”"},{"v":25,"t":"He, leaning back, as he was, on Jesus’ chest, asked him, “Lord, who is it?”"},{"v":26,"t":"Jesus therefore answered, “It is he to whom I will give this piece of bread when I have dipped it.” So when he had dipped the piece of bread, he gave it to Judas, the son of Simon Iscariot."},{"v":27,"t":"After the piece of bread, then Satan entered into him. Then Jesus said to him, “What you do, do quickly.”"},{"v":28,"t":"Now nobody at the table knew why he said this to him."},{"v":29,"t":"For some thought, because Judas had the money box, that Jesus said to him, “Buy what things we need for the feast,” or that he should give something to the poor."},{"v":30,"t":"Therefore having received that morsel, he went out immediately. It was night."},{"v":31,"t":"When he had gone out, Jesus said, “Now the Son of Man has been glorified, and God has been glorified in him."},{"v":32,"t":"If God has been glorified in him, God will also glorify him in himself, and he will glorify him immediately."},{"v":33,"t":"Little children, I will be with you a little while longer. You will seek me, and as I said to the Jews, ‘Where I am going, you can’t come,’ so now I tell you."},{"v":34,"t":"A new commandment I give to you, that you love one another. Just as I have loved you, you also love one another."},{"v":35,"t":"By this everyone will know that you are my disciples, if you have love for one another.”"},{"v":36,"t":"Simon Peter said to him, “Lord, where are you going?” Jesus answered, “Where I am going, you can’t follow now, but you will follow afterwards.”"},{"v":37,"t":"Peter said to him, “Lord, why can’t I follow you now? I will lay down my life for you.”"},{"v":38,"t":"Jesus answered him, “Will you lay down your life for me? Most certainly I tell you, the rooster won’t crow until you have denied me three times."}],"hr":[{"v":1,"t":"Bijaše pred blagdan Pashe. Isus je znao da je došao njegov čas da prijeđe s ovoga svijeta Ocu, budući da je ljubio svoje, one u svijetu, do kraja ih je ljubio."},{"v":2,"t":"I za večerom je đavao već bio ubacio u srce Judi Šimuna Iškariotskoga da ga izda."},{"v":3,"t":"A Isus je znao da mu je Otac sve predao u ruke i da je od Boga izišao te da k Bogu ide pa"},{"v":4,"t":"usta od večere, odloži haljine, uze ubrus i opasa se."},{"v":5,"t":"Nalije zatim vodu u praonik i počne učenicima prati noge i otirati ih ubrusom kojim je bio opasan."},{"v":6,"t":"Dođe tako do Šimuna Petra. A on će mu: “Gospodine! Zar ti da meni pereš noge?”"},{"v":7,"t":"Odgovori mu Isus: “Što ja činim, ti sada ne znaš, ali shvatit ćeš poslije.”"},{"v":8,"t":"Reče mu Petar: “Nećeš mi prati nogu nikada!” Isus mu odvrati: “Ako te ne operem, nećeš imati dijela sa mnom.”"},{"v":9,"t":"Nato će mu Šimun Petar: “Gospodine, onda ne samo noge, nego i ruke i glavu!”"},{"v":10,"t":"Kaže mu Isus: “Tko je okupan, ne treba drugo da opere nego noge - i sav je čist! I vi ste čisti, ali ne svi!”"},{"v":11,"t":"Jer znao je tko će ga izdati. Stoga je i rekao: “Niste svi čisti.”"},{"v":12,"t":"Kad im dakle opra noge, uze svoje haljine, opet sjede i reče im: “Razumijete li što sam vam učinio?"},{"v":13,"t":"Vi me zovete Učiteljem i Gospodinom. Pravo velite jer to i jesam!"},{"v":14,"t":"Ako dakle ja - Gospodin i Učitelj - vama oprah noge, treba da i vi jedni drugima perete noge."},{"v":15,"t":"Primjer sam vam dao da i vi činite kao što ja vama učinih.”"},{"v":16,"t":"Zaista, zaista, kažem vam: nije sluga veći od gospodara niti poslanik od onoga koji ga posla."},{"v":17,"t":"Ako to znate, blago vama budete li tako i činili!”"},{"v":18,"t":"“Ne govorim o svima vama! Ja znam koje izabrah! Ali - neka se ispuni Pismo: Koji blaguje kruh moj, petu na me podiže.”"},{"v":19,"t":"“Već vam sada kažem, prije negoli se dogodi, da kad se dogodi vjerujete da Ja jesam."},{"v":20,"t":"Zaista, zaista, kažem vam: Tko primi onoga kojega ja šaljem, mene prima. A tko mene primi, prima onoga koji je mene poslao.”"},{"v":21,"t":"Rekavši to, potresen u duhu Isus posvjedoči: “Zaista, zaista, kažem vam: jedan će me od vas izdati!”"},{"v":22,"t":"Učenici se zgledahu među sobom u nedoumici o kome to govori."},{"v":23,"t":"A jedan od njegovih učenika - onaj kojega je Isus ljubio - bijaše za stolom Isusu do krila."},{"v":24,"t":"Šimun Petar dade mu znak i reče: “Pitaj tko je taj o kome govori.”"},{"v":25,"t":"Ovaj se privine Isusu uz prsa i upita: “Gospodine, tko je taj?”"},{"v":26,"t":"Isus odgovori: “Onaj je kome ja dadnem umočen zalogaj.”"},{"v":27,"t":"Tada umoči zalogaj, uze ga i dade Judi Šimuna Iškariotskoga. Nakon zalogaja uđe u nj Sotona. Nato mu Isus reče: “Što činiš, učini brzo!”"},{"v":28,"t":"Nijedan od sustolnika nije razumio zašto mu je to rekao."},{"v":29,"t":"Budući da je Juda imao kesu, neki su mislili da mu je Isus rekao: “Kupi što nam treba za blagdan!” - ili neka poda nešto siromasima."},{"v":30,"t":"On dakle uzme zalogaj i odmah iziđe. A bijaše noć."},{"v":31,"t":"Pošto Juda iziđe, reče Isus: “Sada je proslavljen Sin Čovječji i Bog se proslavio u njemu!"},{"v":32,"t":"Ako se Bog proslavio u njemu, i njega će Bog proslaviti u sebi, i uskoro će ga proslaviti!"},{"v":33,"t":"Dječice, još sam malo s vama. Tražit ćete me, ali kao što rekoh Židovima, kažem sada i vama: kamo ja odlazim, vi ne možete doći."},{"v":34,"t":"Zapovijed vam novu dajem: ljubite jedni druge; kao što sam ja ljubio vas tako i vi ljubite jedni druge."},{"v":35,"t":"Po ovom će svi znati da ste moji učenici: ako budete imali ljubavi jedni za druge.”"},{"v":36,"t":"Kaže mu Šimun Petar: “Gospodine, kamo to odlaziš?” Isus mu odgovori: “Kamo ja odlazim, ti zasad ne možeš poći za mnom. No poći ćeš poslije.”"},{"v":37,"t":"Nato će mu Petar: “Gospodine, a zašto sada ne bih mogao poći za tobom? Život ću svoj položiti za tebe!”"},{"v":38,"t":"Odgovori Isus: “Život ćeš svoj položiti za mene? Zaista, zaista, kažem ti: Pijetao neće zapjevati dok me triput ne zatajiš.”"}]},"14":{"fa":[{"v":1,"t":"«دل شما مضطرب نشود! به خدا ایمان آورید به من نیز ایمان آورید."},{"v":2,"t":"در خانه پدر من منزل بسیار است والا به شما می‌گفتم. می‌روم تا برای شما مکانی حاضر کنم،"},{"v":3,"t":"و اگربروم و از برای شما مکانی حاضر کنم، بازمی آیم و شما را برداشته با خود خواهم برد تا جایی که من می‌باشم شما نیز باشید."},{"v":4,"t":"و جایی که من می‌روم می‌دانید و راه را می‌دانید.»"},{"v":5,"t":"توما بدو گفت: «ای آقا نمی دانیم کجا می‌روی. پس چگونه راه را توانیم دانست؟»"},{"v":6,"t":"عیسی بدو گفت: «من راه و راستی و حیات هستم. هیچ‌کس نزد پدر جز به وسیله من نمی آید."},{"v":7,"t":"اگر مرا می‌شناختید، پدر مرانیز می‌شناختید و بعد از این او را می‌شناسید و اورا دیده‌اید.»"},{"v":8,"t":"فیلپس به وی گفت: «ای آقا پدر رابه ما نشان ده که ما را کافی است.»"},{"v":9,"t":"عیسی بدوگفت: «ای فیلیپس در این مدت با شما بوده‌ام، آیامرا نشناخته‌ای؟ کسی‌که مرا دید، پدر را دیده است. پس چگونه تو می‌گویی پدر را به ما نشان ده؟"},{"v":10,"t":"آیا باور نمی کنی که من در پدر هستم و پدردر من است؟ سخنهایی که من به شما می‌گویم ازخود نمی گویم، لکن پدری که در من ساکن است، او این اعمال را می‌کند."},{"v":11,"t":"مرا تصدیق کنید که من در پدر هستم و پدر در من است، والا مرا به‌سبب آن اعمال تصدیق کنید."},{"v":12,"t":"آمین آمین به شمامی گویم هر‌که به من ایمان آرد، کارهایی را که من می‌کنم او نیز خواهد کرد و بزرگتر از اینها نیزخواهد کرد، زیرا که من نزد پدر می‌روم."},{"v":13,"t":"«و هر چیزی را که به اسم من سوال کنید به‌جا خواهم آورد تا پدر در پسر جلال یابد."},{"v":14,"t":"اگرچیزی به اسم من طلب کنید من آن را به‌جا خواهم آورد."},{"v":15,"t":"اگر مرا دوست دارید، احکام مرا نگاه دارید."},{"v":16,"t":"و من از پدر سوال می‌کنم و تسلی دهنده‌ای دیگر به شما عطا خواهد کرد تا همیشه باشما بماند،"},{"v":17,"t":"یعنی روح راستی که جهان نمی تواند او را قبول کند زیرا که او را نمی بیند و نمی شناسد و اما شما او را می‌شناسید، زیرا که باشما می‌ماند و در شما خواهد بود."},{"v":18,"t":"«شما را یتیم نمی گذارم نزد شما می‌آیم."},{"v":19,"t":"بعد از اندک زمانی جهان دیگر مرا نمی بیند واما شما مرا می‌بینید و از این جهت که من زنده‌ام، شما هم خواهید زیست."},{"v":20,"t":"و در آن روز شماخواهید دانست که من در پدر هستم و شما در من و من در شما."},{"v":21,"t":"هر‌که احکام مرا دارد و آنها راحفظ کند، آن است که مرا محبت می‌نماید؛ وآنکه مرا محبت می‌نماید، پدر من او را محبت خواهد نمود و من او را محبت خواهم نمود وخود را به او ظاهر خواهم ساخت.»"},{"v":22,"t":"یهودا، نه آن اسخریوطی، به وی گفت: «ای آقا چگونه می‌خواهی خود را بما بنمایی و نه بر جهان؟»"},{"v":23,"t":"عیسی در جواب او گفت: «اگر کسی مرا محبت نماید، کلام مرا نگاه خواهد داشت و پدرم او رامحبت خواهد نمود و به سوی او آمده، نزد وی مسکن خواهیم گرفت."},{"v":24,"t":"و آنکه مرا محبت ننماید، کلام مرا حفظ نمی کند؛ و کلامی که می‌شنوید از من نیست بلکه از پدری است که مرافرستاد."},{"v":25,"t":"این سخنان را به شما گفتم وقتی که باشما بودم."},{"v":26,"t":"لیکن تسلی دهنده یعنی روح‌القدس که پدر او را به اسم من می‌فرستد، اوهمه‌چیز را به شما تعلیم خواهد داد و آنچه به شما گفتم به یاد شما خواهد آورد."},{"v":27,"t":"سلامتی برای شما می‌گذارم، سلامتی خود را به شمامی دهم. نه‌چنانکه جهان می‌دهد، من به شمامی دهم. دل شما مضطرب و هراسان نباشد."},{"v":28,"t":"شنیده‌اید که من به شما گفتم می‌روم و نزد شمامی آیم. اگر مرا محبت می‌نمودید، خوشحال می‌گشتید که گفتم نزد پدر می‌روم، زیرا که پدربزرگتر از من است."},{"v":29,"t":"و الان قبل از وقوع به شما گفتم تا وقتی که واقع گردد ایمان آورید."},{"v":30,"t":"بعد ازاین بسیار با شما نخواهم گفت، زیرا که رئیس این جهان می‌آید و در من چیزی ندارد."},{"v":31,"t":"لیکن تاجهان بداند که پدر را محبت می‌نمایم، چنانکه پدر به من حکم کرد همانطور می‌کنم. برخیزید ازاینجا برویم."}],"en":[{"v":1,"t":"“Don’t let your heart be troubled. Believe in God. Believe also in me."},{"v":2,"t":"In my Father’s house are many homes. If it weren’t so, I would have told you. I am going to prepare a place for you."},{"v":3,"t":"If I go and prepare a place for you, I will come again and will receive you to myself; that where I am, you may be there also."},{"v":4,"t":"You know where I go, and you know the way.”"},{"v":5,"t":"Thomas said to him, “Lord, we don’t know where you are going. How can we know the way?”"},{"v":6,"t":"Jesus said to him, “I am the way, the truth, and the life. No one comes to the Father, except through me."},{"v":7,"t":"If you had known me, you would have known my Father also. From now on, you know him and have seen him.”"},{"v":8,"t":"Philip said to him, “Lord, show us the Father, and that will be enough for us.”"},{"v":9,"t":"Jesus said to him, “Have I been with you such a long time, and do you not know me, Philip? He who has seen me has seen the Father. How do you say, ‘Show us the Father’?"},{"v":10,"t":"Don’t you believe that I am in the Father, and the Father in me? The words that I tell you, I speak not from myself; but the Father who lives in me does his works."},{"v":11,"t":"Believe me that I am in the Father, and the Father in me; or else believe me for the very works’ sake."},{"v":12,"t":"Most certainly I tell you, he who believes in me, the works that I do, he will do also; and he will do greater works than these, because I am going to my Father."},{"v":13,"t":"Whatever you will ask in my name, I will do it, that the Father may be glorified in the Son."},{"v":14,"t":"If you will ask anything in my name, I will do it."},{"v":15,"t":"If you love me, keep my commandments."},{"v":16,"t":"I will pray to the Father, and he will give you another Counselor, that he may be with you forever:"},{"v":17,"t":"the Spirit of truth, whom the world can’t receive, for it doesn’t see him and doesn’t know him. You know him, for he lives with you and will be in you."},{"v":18,"t":"I will not leave you orphans. I will come to you."},{"v":19,"t":"Yet a little while, and the world will see me no more; but you will see me. Because I live, you will live also."},{"v":20,"t":"In that day you will know that I am in my Father, and you in me, and I in you."},{"v":21,"t":"One who has my commandments and keeps them, that person is one who loves me. One who loves me will be loved by my Father, and I will love him, and will reveal myself to him.”"},{"v":22,"t":"Judas (not Iscariot) said to him, “Lord, what has happened that you are about to reveal yourself to us, and not to the world?”"},{"v":23,"t":"Jesus answered him, “If a man loves me, he will keep my word. My Father will love him, and we will come to him and make our home with him."},{"v":24,"t":"He who doesn’t love me doesn’t keep my words. The word which you hear isn’t mine, but the Father’s who sent me."},{"v":25,"t":"“I have said these things to you while still living with you."},{"v":26,"t":"But the Counselor, the Holy Spirit, whom the Father will send in my name, will teach you all things, and will remind you of all that I said to you."},{"v":27,"t":"Peace I leave with you. My peace I give to you; not as the world gives, I give to you. Don’t let your heart be troubled, neither let it be fearful."},{"v":28,"t":"You heard how I told you, ‘I am going away, and I will come back to you.’ If you loved me, you would have rejoiced because I said ‘I am going to my Father;’ for the Father is greater than I."},{"v":29,"t":"Now I have told you before it happens so that when it happens, you may believe."},{"v":30,"t":"I will no more speak much with you, for the prince of the world comes, and he has nothing in me."},{"v":31,"t":"But that the world may know that I love the Father, and as the Father commanded me, even so I do. Arise, let’s go from here."}],"hr":[{"v":1,"t":"“Neka se ne uznemiruje srce vaše! Vjerujte u Boga i u mene vjerujte!"},{"v":2,"t":"U domu Oca mojega ima mnogo stanova. Da nema, zar bih vam rekao: 'Idem pripraviti vam mjesto'?"},{"v":3,"t":"Kad odem i pripravim vam mjesto, ponovno ću doći i uzeti vas k sebi da i vi budete gdje sam ja."},{"v":4,"t":"A kamo ja odlazim, znate put.”"},{"v":5,"t":"Reče mu Toma: “Gospodine, ne znamo kamo odlaziš. Kako onda možemo put znati?”"},{"v":6,"t":"Odgovori mu Isus: “Ja sam Put i Istina i Život: nitko ne dolazi Ocu osim po meni."},{"v":7,"t":"Da ste upoznali mene, i Oca biste moga upoznali. Od sada ga i poznajete i vidjeli ste ga.”"},{"v":8,"t":"Kaže mu Filip: “Gospodine, pokaži nam Oca i dosta nam je!”"},{"v":9,"t":"Nato će mu Isus: “Filipe, toliko sam vremena s vama i još me ne poznaš?” “Tko je vidio mene, vidio je i Oca. Kako ti onda kažeš: 'Pokaži nam Oca'?"},{"v":10,"t":"Ne vjeruješ li da sam ja u Ocu i Otac u meni? Riječi koje vam govorim, od sebe ne govorim: Otac koji prebiva u meni čini djela svoja."},{"v":11,"t":"Vjerujte mi: ja sam u Ocu i Otac u meni. Ako ne inače, zbog samih djela vjerujte."},{"v":12,"t":"Zaista, zaista, kažem vam: Tko vjeruje u mene, činit će djela koja ja činim; da veća će od njih činiti jer ja odlazim Ocu."},{"v":13,"t":"I što god zaištete u moje ime, učinit ću, da se proslavi Otac u Sinu."},{"v":14,"t":"Ako me što zaištete u moje ime, učinit ću.”"},{"v":15,"t":"“Ako me ljubite, zapovijedi ćete moje čuvati."},{"v":16,"t":"I ja ću moliti Oca i on će vam dati drugoga Branitelja da bude s vama zauvijek:"},{"v":17,"t":"Duha Istine, kojega svijet ne može primiti jer ga ne vidi i ne poznaje. Vi ga poznajete jer kod vas ostaje i u vama je."},{"v":18,"t":"Neću vas ostaviti kao siročad; doći ću k vama."},{"v":19,"t":"Još malo i svijet me više neće vidjeti, no vi ćete me vidjeti jer ja živim i vi ćete živjeti."},{"v":20,"t":"U onaj ćete dan spoznati da sam ja u Ocu svom i vi u meni i ja u vama."},{"v":21,"t":"Tko ima moje zapovijedi i čuva ih, taj me ljubi; a tko mene ljubi, njega će ljubiti Otac moj, i ja ću ljubiti njega i njemu se očitovati.”"},{"v":22,"t":"Kaže mu Juda, ne Iškariotski: “Gospodine, kako to da ćeš se očitovati nama, a ne svijetu?”"},{"v":23,"t":"Odgovori mu Isus: “Ako me tko ljubi, čuvat će moju riječ pa će i Otac moj ljubiti njega i k njemu ćemo doći i kod njega se nastaniti."},{"v":24,"t":"Tko mene ne ljubi, riječi mojih ne čuva. A riječ koju slušate nije moja, nego Oca koji me posla."},{"v":25,"t":"To sam vam govorio dok sam boravio s vama."},{"v":26,"t":"Branitelj - Duh Sveti, koga će Otac poslati u moje ime, poučavat će vas o svemu i dozivati vam u pamet sve što vam ja rekoh."},{"v":27,"t":"Mir vam ostavljam, mir vam svoj dajem. Dajem vam ga, ali ne kao što svijet daje. Neka se ne uznemiruje vaše srce i neka se ne straši."},{"v":28,"t":"Čuli ste, rekoh vam: 'Odlazim i vraćam se k vama.' Kad biste me ljubili, radovali biste se što idem Ocu jer Otac je veći od mene."},{"v":29,"t":"Kazao sam vam to sada, prije negoli se dogodi, da vjerujete kad se dogodi."},{"v":30,"t":"Neću više s vama mnogo govoriti jer dolazi knez svijeta. Protiv mene ne može on ništa."},{"v":31,"t":"Ali neka svijet upozna da ja ljubim Oca i da tako činim kako mi je zapovjedio Otac. Ustanite, pođimo odavde!”"}]},"15":{"fa":[{"v":1,"t":"«من تاک حقیقی هستم و پدر من باغبان است."},{"v":2,"t":"هر شاخه‌ای در من که میوه نیاورد، آن را دور می‌سازد و هر‌چه میوه آرد آن راپاک می‌کند تا بیشتر میوه آورد."},{"v":3,"t":"الحال شما به‌سبب کلامی که به شما گفته‌ام پاک هستید."},{"v":4,"t":"در من بمانید و من در شما. همچنانکه شاخه از خودنمی تواند میوه آورد اگر در تاک نماند، همچنین شما نیز اگر در من نمانید."},{"v":5,"t":"من تاک هستم و شماشاخه‌ها. آنکه در من می‌ماند و من در او، میوه بسیار می‌آورد زیرا که جدا از من هیچ نمی توانیدکرد."},{"v":6,"t":"اگر کسی در من نماند، مثل شاخه بیرون انداخته می‌شود و می‌خشکد و آنها را جمع کرده، در آتش می‌اندازند و سوخته می‌شود."},{"v":7,"t":"اگر در من بمانید و کلام من در شما بماند، آنچه خواهیدبطلبید که برای شما خواهد شد."},{"v":8,"t":"جلال پدر من آشکارا می‌شود به اینکه میوه بسیار بیاورید وشاگرد من بشوید."},{"v":9,"t":"همچنان‌که پدر مرا محبت نمود، من نیز شما را محبت نمودم؛ در محبت من بمانید."},{"v":10,"t":"اگر احکام مرا نگاه دارید، در محبت من خواهید ماند، چنانکه من احکام پدر خود را نگاه داشته‌ام و در محبت او می‌مانم."},{"v":11,"t":"این را به شماگفتم تا خوشی من در شما باشد و شادی شماکامل گردد."},{"v":12,"t":"«این است حکم من که یکدیگر را محبت نمایید، همچنان‌که شما را محبت نمودم."},{"v":13,"t":"کسی محبت بزرگتر از این ندارد که جان خودرا بجهت دوستان خود بدهد."},{"v":14,"t":"شما دوست من هستید اگر آنچه به شما حکم می‌کنم به‌جا آرید."},{"v":15,"t":"دیگر شما را بنده نمی خوانم زیرا که بنده آنچه آقایش می‌کند نمی داند؛ لکن شما را دوست خوانده‌ام زیرا که هرچه از پدر شنیده‌ام به شمابیان کردم."},{"v":16,"t":"شما مرا برنگزیدید، بلکه من شما رابرگزیدم و شما را مقرر کردم تا شما بروید و میوه آورید و میوه شما بماند تا هر‌چه از پدر به اسم من طلب کنید به شما عطا کند."},{"v":17,"t":"به این چیزها شما را حکم می‌کنم تایکدیگر را محبت نمایید."},{"v":18,"t":"«اگر جهان شما رادشمن دارد، بدانید که پیشتر از شما مرا دشمن داشته است."},{"v":19,"t":"اگر از جهان می‌بودید، جهان خاصان خود را دوست می‌داشت. لکن چونکه ازجهان نیستید بلکه من شما را از جهان برگزیده‌ام، از این سبب جهان با شما دشمنی می‌کند."},{"v":20,"t":"به‌خاطر آرید کلامی را که به شما گفتم: غلام بزرگتراز آقای خود نیست. اگر مرا زحمت دادند، شما رانیز زحمت خواهند داد، اگر کلام مرا نگاه داشتند، کلام شما را هم نگاه خواهند داشت."},{"v":21,"t":"لکن بجهت اسم من جمیع این کارها را به شما خواهندکرد زیرا که فرستنده مرا نمی شناسند."},{"v":22,"t":"اگرنیامده بودم و به ایشان تکلم نکرده، گناه نمی داشتند؛ و اما الان عذری برای گناه خودندارند."},{"v":23,"t":"هر‌که مرا دشمن دارد پدر مرا نیز دشمن دارد."},{"v":24,"t":"و اگر در میان ایشان کارهایی نکرده بودم که غیر از من کسی هرگز نکرده بود، گناه نمی داشتند. ولیکن اکنون دیدند و دشمن داشتند مرا و پدر مرا نیز."},{"v":25,"t":"بلکه تا تمام شودکلامی که در شریعت ایشان مکتوب است که “مرابی سبب دشمن داشتند.”"},{"v":26,"t":"لیکن چون تسلی دهنده که او را از جانب پدر نزد شما می‌فرستم آید، یعنی روح راستی که از پدر صادر می‌گردد، او بر من شهادت خواهد داد."},{"v":27,"t":"و شما نیزشهادت خواهید داد زیرا که از ابتدا با من بوده‌اید."}],"en":[{"v":1,"t":"“I am the true vine, and my Father is the farmer."},{"v":2,"t":"Every branch in me that doesn’t bear fruit, he takes away. Every branch that bears fruit, he prunes, that it may bear more fruit."},{"v":3,"t":"You are already pruned clean because of the word which I have spoken to you."},{"v":4,"t":"Remain in me, and I in you. As the branch can’t bear fruit by itself unless it remains in the vine, so neither can you, unless you remain in me."},{"v":5,"t":"I am the vine. You are the branches. He who remains in me and I in him bears much fruit, for apart from me you can do nothing."},{"v":6,"t":"If a man doesn’t remain in me, he is thrown out as a branch and is withered; and they gather them, throw them into the fire, and they are burned."},{"v":7,"t":"If you remain in me, and my words remain in you, you will ask whatever you desire, and it will be done for you."},{"v":8,"t":"“In this my Father is glorified, that you bear much fruit; and so you will be my disciples."},{"v":9,"t":"Even as the Father has loved me, I also have loved you. Remain in my love."},{"v":10,"t":"If you keep my commandments, you will remain in my love, even as I have kept my Father’s commandments and remain in his love."},{"v":11,"t":"I have spoken these things to you, that my joy may remain in you, and that your joy may be made full."},{"v":12,"t":"“This is my commandment, that you love one another, even as I have loved you."},{"v":13,"t":"Greater love has no one than this, that someone lay down his life for his friends."},{"v":14,"t":"You are my friends if you do whatever I command you."},{"v":15,"t":"No longer do I call you servants, for the servant doesn’t know what his lord does. But I have called you friends, for everything that I heard from my Father, I have made known to you."},{"v":16,"t":"You didn’t choose me, but I chose you and appointed you, that you should go and bear fruit, and that your fruit should remain; that whatever you will ask of the Father in my name, he may give it to you."},{"v":17,"t":"“I command these things to you, that you may love one another."},{"v":18,"t":"If the world hates you, you know that it has hated me before it hated you."},{"v":19,"t":"If you were of the world, the world would love its own. But because you are not of the world, since I chose you out of the world, therefore the world hates you."},{"v":20,"t":"Remember the word that I said to you: ‘A servant is not greater than his lord.’ If they persecuted me, they will also persecute you. If they kept my word, they will also keep yours."},{"v":21,"t":"But they will do all these things to you for my name’s sake, because they don’t know him who sent me."},{"v":22,"t":"If I had not come and spoken to them, they would not have had sin; but now they have no excuse for their sin."},{"v":23,"t":"He who hates me, hates my Father also."},{"v":24,"t":"If I hadn’t done among them the works which no one else did, they wouldn’t have had sin. But now they have seen and also hated both me and my Father."},{"v":25,"t":"But this happened so that the word may be fulfilled which was written in their law, ‘They hated me without a cause.’"},{"v":26,"t":"“When the Counselor has come, whom I will send to you from the Father, the Spirit of truth, who proceeds from the Father, he will testify about me."},{"v":27,"t":"You will also testify, because you have been with me from the beginning."}],"hr":[{"v":1,"t":"“Ja sam istinski trs, a Otac moj - vinogradar."},{"v":2,"t":"Svaku lozu na meni koja ne donosi roda on siječe, a svaku koja rod donosi čisti da više roda donese."},{"v":3,"t":"Vi ste već očišćeni po riječi koju sam vam zborio."},{"v":4,"t":"Ostanite u meni i ja u vama. Kao što loza ne može donijeti roda sama od sebe, ako ne ostane na trsu, tako ni vi ako ne ostanete u meni."},{"v":5,"t":"Ja sam trs, vi loze. Tko ostaje u meni i ja u njemu, taj donosi mnogo roda. Uistinu, bez mene ne možete učiniti ništa."},{"v":6,"t":"Ako tko ne ostane u meni, izbace ga kao lozu i usahne. Takve onda skupe i bace u oganj te gore."},{"v":7,"t":"Ako ostanete u meni i riječi moje ako ostanu u vama, što god hoćete, ištite i bit će vam."},{"v":8,"t":"Ovim se proslavlja Otac moj: da donosite mnogo roda i da budete moji učenici."},{"v":9,"t":"Kao što je Otac ljubio mene tako sam i ja ljubio vas; ostanite u mojoj ljubavi."},{"v":10,"t":"Budete li čuvali moje zapovijedi, ostat ćete u mojoj ljubavi; kao što sam i ja čuvao zapovijedi Oca svoga te ostajem u ljubavi njegovoj."},{"v":11,"t":"To sam vam govorio da moja radost bude u vama i da vaša radost bude potpuna."},{"v":12,"t":"Ovo je moja zapovijed: ljubite jedni druge kao što sam ja vas ljubio!"},{"v":13,"t":"Veće ljubavi nitko nema od ove: da tko život svoj položi za svoje prijatelje."},{"v":14,"t":"Vi ste prijatelji moji ako činite što vam zapovijedam."},{"v":15,"t":"Više vas ne zovem slugama jer sluga ne zna što radi njegov gospodar; vas sam nazvao prijateljima jer vam priopćih sve što sam čuo od Oca svoga."},{"v":16,"t":"Ne izabraste vi mene, nego ja izabrah vas i postavih vas da idete i rod donosite i rod vaš da ostane te vam Otac dadne što ga god zaištete u moje ime."},{"v":17,"t":"Ovo vam zapovijedam: da ljubite jedni druge.”"},{"v":18,"t":"“Ako vas svijet mrzi, znajte da je mene mrzio prije nego vas."},{"v":19,"t":"Kad biste bili od svijeta, svijet bi svoje ljubio; no budući da niste od svijeta, nego sam vas ja izabrao iz svijeta, zbog toga vas svijet mrzi."},{"v":20,"t":"Sjećajte se riječi koju vam rekoh: 'Nije sluga veći od svoga gospodara.' Ako su mene progonili, i vas će progoniti; ako su moju riječ čuvali, da vašu će čuvati."},{"v":21,"t":"A sve će to poduzimati protiv vas poradi imena moga jer ne znaju onoga koji mene posla."},{"v":22,"t":"Da nisam došao i da im nisam govorio, ne bi imali grijeha; no sada nemaju izgovora za svoj grijeh."},{"v":23,"t":"Tko mene mrzi, mrzi i Oca mojega."},{"v":24,"t":"Da nisam učinio među njima djela kojih nitko drugi ne čini, ne bi imali grijeha; a sada vidješe pa ipak zamrziše i mene i Oca mojega."},{"v":25,"t":"No neka se ispuni riječ napisana u njihovu Zakonu: Mrze me nizašto."},{"v":26,"t":"A kada dođe Branitelj koga ću vam poslati od Oca - Duh Istine koji od Oca izlazi - on će svjedočiti za mene."},{"v":27,"t":"I vi ćete svjedočiti jer ste od početka sa mnom."}]},"16":{"fa":[{"v":1,"t":"این را به شما گفتم تا لغزش نخورید."},{"v":2,"t":"شما را از کنایس بیرون خواهندنمود؛ بلکه ساعتی می‌آید که هر‌که شما را بکشد، گمان برد که خدا را خدمت می‌کند."},{"v":3,"t":"و این کارهارا با شما خواهند کرد، بجهت آنکه نه پدر راشناخته‌اند و نه مرا."},{"v":4,"t":"لیکن این را به شما گفتم تاوقتی که ساعت آید به‌خاطر آورید که من به شماگفتم. و این را از اول به شما نگفتم، زیرا که با شمابودم."},{"v":5,"t":"«اما الان نزد فرستنده خود می‌روم و کسی ازشما از من نمی پرسد به کجا می‌روی."},{"v":6,"t":"ولیکن چون این را به شما گفتم، دل شما از غم پر شده است."},{"v":7,"t":"و من به شما راست می‌گویم که رفتن من برای شما مفید است، زیرا اگر نروم تسلی دهنده نزد شما نخواهد آمد. اما اگر بروم او را نزد شمامی فرستم."},{"v":8,"t":"و چون او آید، جهان را بر گناه وعدالت و داوری ملزم خواهد نمود."},{"v":9,"t":"اما بر گناه، زیرا که به من ایمان نمی آورند."},{"v":10,"t":"و اما بر عدالت، از آن سبب که نزد پدر خود می‌روم و دیگر مرانخواهید دید."},{"v":11,"t":"و اما بر داوری، از آنرو که بررئیس این جهان حکم شده است."},{"v":12,"t":"«و بسیار چیزهای دیگر نیز دارم به شمابگویم، لکن الان طاقت تحمل آنها را ندارید."},{"v":13,"t":"ولیکن چون او یعنی روح راستی آید، شما را به جمیع راستی هدایت خواهد کرد زیرا که از خودتکلم نمی کند بلکه به آنچه شنیده است سخن خواهد گفت و از امور آینده به شما خبر‌خواهدداد."},{"v":14,"t":"او مرا جلال خواهد داد زیرا که از آنچه آن من است خواهد گرفت و به شما خبر‌خواهد داد."},{"v":15,"t":"هر‌چه از آن پدر است، از آن من است. از این جهت گفتم که از آنچه آن من است، می‌گیرد و به شما خبر‌خواهد داد."},{"v":16,"t":"«بعد از اندکی مرانخواهید دید و بعد از اندکی باز مرا خواهید دیدزیرا که نزد پدر می‌روم.»"},{"v":17,"t":"آنگاه بعضی از شاگردانش به یکدیگرگفتند: «چه چیز است اینکه به ما می‌گوید که اندکی مرا نخواهید دید و بعد از اندکی باز مراخواهید دید و زیرا که نزد پدر می‌روم؟»"},{"v":18,"t":"پس گفتند: «چه چیز است این اندکی که می‌گوید؟ نمی دانیم چه می‌گوید.»"},{"v":19,"t":"عیسی چون دانست که می‌خواهند از او سوال کنند، بدیشان گفت: «آیا در میان خود از این سوال می‌کنید که گفتم اندکی دیگر مرا نخواهید دید پس بعد از اندکی بازمرا خواهید دید."},{"v":20,"t":"آمین آمین به شما می‌گویم که شما گریه و زاری خواهید کرد و جهان شادی خواهد نمود. شما محزون می‌شوید لکن حزن شما به خوشی مبدل خواهد شد."},{"v":21,"t":"زن در حین زاییدن محزون می‌شود، زیرا که ساعت او رسیده است. و لیکن چون طفل را زایید، آن زحمت رادیگر یاد نمی آورد به‌سبب خوشی از اینکه انسانی در جهان تولد یافت."},{"v":22,"t":"پس شما همچنین الان محزون می‌باشید، لکن باز شما را خواهم دیدو دل شما خوش خواهد گشت و هیچ‌کس آن خوشی را از شما نخواهد گرفت."},{"v":23,"t":"و در آن روزچیزی از من سوال نخواهید کرد. آمین آمین به شما می‌گویم که هر‌آنچه از پدر به اسم من طلب کنید به شما عطا خواهد کرد."},{"v":24,"t":"تا کنون به اسم من چیزی طلب نکردید، بطلبید تا بیابید و خوشی شما کامل گردد."},{"v":25,"t":"این چیزها را به مثلها به شماگفتم، لکن ساعتی می‌آید که دیگر به مثلها به شماحرف نمی زنم بلکه از پدر به شما آشکارا خبرخواهم داد."},{"v":26,"t":"«در آن روز به اسم من طلب خواهید کرد وبه شما نمی گویم که من بجهت شما از پدر سوال می‌کنم،"},{"v":27,"t":"زیرا خود پدر شما را دوست می‌دارد، چونکه شما مرا دوست داشتید و ایمان آوردیدکه من از نزد خدا بیرون آمدم."},{"v":28,"t":"از نزد پدر بیرون آمدم و در جهان وارد شدم، و باز جهان را گذارده، نزد پدر می‌روم.»"},{"v":29,"t":"شاگردانش بدو گفتند: «هان اکنون علانیه سخن می‌گویی و هیچ مثل نمی گویی."},{"v":30,"t":"الان دانستیم که همه‌چیز رامی دانی و لازم نیست که کسی از تو بپرسد. بدین جهت باور می‌کنیم که از خدا بیرون آمدی.»"},{"v":31,"t":"عیسی به ایشان جواب داد: «آیا الان باورمی کنید؟"},{"v":32,"t":"اینک ساعتی می‌آید بلکه الان آمده است که متفرق خواهید شد هریکی به نزدخاصان خود و مرا تنها خواهید گذارد. لیکن تنهانیستم زیرا که پدر با من است."},{"v":33,"t":"بدین چیزها به شما تکلم کردم تا در من سلامتی داشته باشید. در جهان برای شما زحمت خواهد شد. و لکن خاطرجمع دارید زیرا که من بر جهان غالب شده‌ام.»"}],"en":[{"v":1,"t":"“I have said these things to you so that you wouldn’t be caused to stumble."},{"v":2,"t":"They will put you out of the synagogues. Yes, the time is coming that whoever kills you will think that he offers service to God."},{"v":3,"t":"They will do these things because they have not known the Father nor me."},{"v":4,"t":"But I have told you these things so that when the time comes, you may remember that I told you about them. I didn’t tell you these things from the beginning, because I was with you."},{"v":5,"t":"But now I am going to him who sent me, and none of you asks me, ‘Where are you going?’"},{"v":6,"t":"But because I have told you these things, sorrow has filled your heart."},{"v":7,"t":"Nevertheless I tell you the truth: It is to your advantage that I go away; for if I don’t go away, the Counselor won’t come to you. But if I go, I will send him to you."},{"v":8,"t":"When he has come, he will convict the world about sin, about righteousness, and about judgment;"},{"v":9,"t":"about sin, because they don’t believe in me;"},{"v":10,"t":"about righteousness, because I am going to my Father, and you won’t see me any more;"},{"v":11,"t":"about judgment, because the prince of this world has been judged."},{"v":12,"t":"“I still have many things to tell you, but you can’t bear them now."},{"v":13,"t":"However, when he, the Spirit of truth, has come, he will guide you into all truth, for he will not speak from himself; but whatever he hears, he will speak. He will declare to you things that are coming."},{"v":14,"t":"He will glorify me, for he will take from what is mine and will declare it to you."},{"v":15,"t":"All things that the Father has are mine; therefore I said that he takes of mine and will declare it to you."},{"v":16,"t":"“A little while, and you will not see me. Again a little while, and you will see me.”"},{"v":17,"t":"Some of his disciples therefore said to one another, “What is this that he says to us, ‘A little while, and you won’t see me, and again a little while, and you will see me;’ and, ‘Because I go to the Father’?”"},{"v":18,"t":"They said therefore, “What is this that he says, ‘A little while’? We don’t know what he is saying.”"},{"v":19,"t":"Therefore Jesus perceived that they wanted to ask him, and he said to them, “Do you inquire among yourselves concerning this, that I said, ‘A little while, and you won’t see me, and again a little while, and you will see me’?"},{"v":20,"t":"Most certainly I tell you that you will weep and lament, but the world will rejoice. You will be sorrowful, but your sorrow will be turned into joy."},{"v":21,"t":"A woman, when she gives birth, has sorrow because her time has come. But when she has delivered the child, she doesn’t remember the anguish any more, for the joy that a human being is born into the world."},{"v":22,"t":"Therefore you now have sorrow, but I will see you again, and your heart will rejoice, and no one will take your joy away from you."},{"v":23,"t":"“In that day you will ask me no questions. Most certainly I tell you, whatever you may ask of the Father in my name, he will give it to you."},{"v":24,"t":"Until now, you have asked nothing in my name. Ask, and you will receive, that your joy may be made full."},{"v":25,"t":"“I have spoken these things to you in figures of speech. But the time is coming when I will no more speak to you in figures of speech, but will tell you plainly about the Father."},{"v":26,"t":"In that day you will ask in my name; and I don’t say to you that I will pray to the Father for you,"},{"v":27,"t":"for the Father himself loves you, because you have loved me, and have believed that I came from God."},{"v":28,"t":"I came from the Father and have come into the world. Again, I leave the world and go to the Father.”"},{"v":29,"t":"His disciples said to him, “Behold, now you are speaking plainly, and using no figures of speech."},{"v":30,"t":"Now we know that you know all things, and don’t need for anyone to question you. By this we believe that you came from God.”"},{"v":31,"t":"Jesus answered them, “Do you now believe?"},{"v":32,"t":"Behold, the time is coming, yes, and has now come, that you will be scattered, everyone to his own place, and you will leave me alone. Yet I am not alone, because the Father is with me."},{"v":33,"t":"I have told you these things, that in me you may have peace. In the world you have trouble; but cheer up! I have overcome the world.”"}],"hr":[{"v":1,"t":"To sam vam govorio da se ne sablaznite."},{"v":2,"t":"Izopćavat će vas iz sinagoga. Štoviše, dolazi čas kad će svaki koji vas ubije misliti da služi Bogu."},{"v":3,"t":"A to će činiti jer ne upoznaše ni Oca ni mene."},{"v":4,"t":"Govorio sam vam ovo da se, kada dođe vrijeme, sjetite da sam vam rekao.” “S početka vam ne rekoh ovo jer bijah s vama."},{"v":5,"t":"A sada odlazim k onome koji me posla i nitko me od vas ne pita: 'Kamo ideš?'"},{"v":6,"t":"Naprotiv, žalošću se ispunilo vaše srce što vam ovo kazah."},{"v":7,"t":"No kažem vam istinu: bolje je za vas da ja odem: jer ako ne odem, Branitelj neće doći k vama; ako pak odem, poslat ću ga k vama."},{"v":8,"t":"A kad on dođe, pokazat će svijetu što je grijeh, što li pravednost, a što osuda:"},{"v":9,"t":"grijeh je što ne vjeruju u mene;"},{"v":10,"t":"pravednost - što odlazim k Ocu i više me ne vidite;"},{"v":11,"t":"a osuda - što je knez ovoga svijeta osuđen."},{"v":12,"t":"Još vam mnogo imam kazati, ali sada ne možete nositi."},{"v":13,"t":"No kada dođe on - Duh Istine - upućivat će vas u svu istinu; jer neće govoriti sam od sebe, nego će govoriti što čuje i navješćivat će vam ono što dolazi."},{"v":14,"t":"On će mene proslavljati jer će od mojega uzimati i navješćivati vama."},{"v":15,"t":"Sve što ima Otac, moje je. Zbog toga vam rekoh: od mojega uzima i - navješćivat će vama.”"},{"v":16,"t":"“Malo, i više me nećete vidjeti; i opet malo, pa ćete me vidjeti.”"},{"v":17,"t":"Nato se neki od učenika zapitkivahu: “Što je to što nam kaže: 'Malo, i nećete me vidjeti, i opet malo, pa ćete me vidjeti' i 'Odlazim Ocu'?”"},{"v":18,"t":"Govorahu dakle: “Što je to što kaže 'Malo'? Ne znamo što govori.”"},{"v":19,"t":"Isus spozna da su ga htjeli pitati pa im reče: “Pitate se među sobom o tome što kazah: 'Malo, i nećete me vidjeti; i opet malo, pa ćete me vidjeti'?"},{"v":20,"t":"Zaista, zaista, kažem vam: vi ćete plakati i jaukati, a svijet će se veseliti. Vi ćete se žalostiti, ali žalost će se vaša okrenuti u radost."},{"v":21,"t":"Žena kad rađa, žalosna je jer je došao njezin čas; ali kad rodi djetešce, ne spominje se više muke od radosti što se čovjek rodio na svijet."},{"v":22,"t":"Tako dakle i vi: sad ste u žalosti, no ja ću vas opet vidjeti; i srce će vam se radovati i radosti vaše nitko vam oteti neće."},{"v":23,"t":"U onaj me dan nećete ništa više pitati. Zaista, zaista, kažem vam: što god zaištete u Oca, dat će vam u moje ime."},{"v":24,"t":"Dosad niste iskali ništa u moje ime. Ištite i primit ćete da radost vaša bude potpuna!”"},{"v":25,"t":"“To sam vam govorio u poredbama. Dolazi čas kad vam više neću govoriti u poredbama, nego ću vam otvoreno navješćivati Oca."},{"v":26,"t":"U onaj dan iskat ćete u moje ime i ne velim vam da ću ja moliti Oca za vas."},{"v":27,"t":"Ta sam vas Otac ljubi jer vi ste mene ljubili i vjerovali da sam ja od Boga izišao."},{"v":28,"t":"Izišao sam od Oca i došao na svijet. Opet ostavljam svijet i odlazim Ocu.”"},{"v":29,"t":"Kažu mu učenici: “Evo, sad otvoreno zboriš i nikakvon se poredbom ne služiš."},{"v":30,"t":"Sada znamo da sve znaš i ne treba da te tko pita. Stoga vjerujemo da si izišao od Boga.”"},{"v":31,"t":"Odgovori im Isus: “Sada vjerujete?"},{"v":32,"t":"Evo dolazi čas i već je došao: raspršit ćete se svaki na svoju stranu i mene ostaviti sama. No ja nisam sam jer Otac je sa mnom."},{"v":33,"t":"To vam rekoh da u meni mir imate. U svijetu imate muku, ali hrabri budite - ja sam pobijedio svijet!”"}]},"17":{"fa":[{"v":1,"t":"عیسی چون این را گفت، چشمان خودرا به طرف آسمان بلند کرده، گفت: «ای پدر ساعت رسیده است. پسر خود را جلال بده تاپسرت نیز تو را جلال دهد."},{"v":2,"t":"همچنان‌که او را برهر بشری قدرت داده‌ای تا هر‌چه بدو داده‌ای به آنها حیات جاودانی بخشد."},{"v":3,"t":"و حیات جاودانی‌این است که تو را خدای واحد حقیقی و عیسی مسیح را که فرستادی بشناسند."},{"v":4,"t":"من بر روی زمین تو را جلال دادم و کاری را که به من سپردی تابکنم، به‌کمال رسانیدم."},{"v":5,"t":"و الان تو‌ای پدر مرا نزدخود جلال ده، به همان جلالی که قبل از آفرینش جهان نزد تو داشتم."},{"v":6,"t":"«اسم تو را به آن مردمانی که از جهان به من عطا کردی ظاهر ساختم. از آن تو بودند و ایشان را به من دادی و کلام تو را نگاه داشتند."},{"v":7,"t":"و الان دانستند آنچه به من داده‌ای از نزد تو می‌باشد."},{"v":8,"t":"زیرا کلامی را که به من سپردی، بدیشان سپردم و ایشان قبول کردند و از روی یقین دانستند که ازنزد تو بیرون آمدم و ایمان آوردند که تو مرافرستادی."},{"v":9,"t":"من بجهت اینها سوال می‌کنم و برای جهان سوال نمی کنم، بلکه از برای کسانی که به من داده‌ای، زیرا که از آن تو می‌باشند."},{"v":10,"t":"و آنچه ازآن من است از آن تو است و آنچه از آن تو است از آن من است و در آنها جلال یافته‌ام."},{"v":11,"t":"بعد از این در جهان نیستم اما اینها در جهان هستند و من نزدتو می‌آیم. ای پدر قدوس اینها را که به من داده‌ای، به اسم خود نگاه دار تا یکی باشندچنانکه ما هستیم."},{"v":12,"t":"مادامی که با ایشان در جهان بودم، من ایشان را به اسم تو نگاه داشتم، و هر کس را که به من داده‌ای حفظ نمودم که یکی از ایشان هلاک نشد، مگر پسر هلاکت تا کتاب تمام شود."},{"v":13,"t":"و اما الان نزد تو می‌آیم. و این را در جهان می‌گویم تا خوشی مرا در خود کامل داشته باشند."},{"v":14,"t":"من کلام تو را به ایشان دادم و جهان ایشان رادشمن داشت زیرا که از جهان نیستند، همچنان‌که من نیز از جهان نیستم."},{"v":15,"t":"خواهش نمی کنم که ایشان را از جهان ببری، بلکه تا ایشان را از شریرنگاه داری."},{"v":16,"t":"ایشان از جهان نیستند چنانکه من از جهان نمی باشم."},{"v":17,"t":"ایشان را به راستی خودتقدیس نما. کلام تو راستی است."},{"v":18,"t":"همچنان‌که مرا در جهان فرستادی، من نیز ایشان را در جهان فرستادم."},{"v":19,"t":"و بجهت ایشان من خود را تقدیس می‌کنم تا ایشان نیز در راستی، تقدیس کرده شوند."},{"v":20,"t":"«و نه برای اینها فقط سوال می‌کنم، بلکه برای آنها نیز که به وسیله کلام ایشان به من ایمان خواهند‌آورد."},{"v":21,"t":"تا همه یک گردند چنانکه تو‌ای پدر، در من هستی و من در تو، تا ایشان نیز در مایک باشند تا جهان ایمان آرد که تو مرا فرستادی."},{"v":22,"t":"و من جلالی را که به من دادی به ایشان دادم تا یک باشند چنانکه ما یک هستیم."},{"v":23,"t":"من در ایشان و تو در من، تا در یکی کامل گردند و تا جهان بداندکه تو مرا فرستادی و ایشان را محبت نمودی چنانکه مرا محبت نمودی."},{"v":24,"t":"‌ای پدر می‌خواهم آنانی که به من داده‌ای با من باشند در جایی که من می‌باشم تا جلال مرا که به من داده‌ای ببینند، زیراکه مرا پیش از بنای جهان محبت نمودی."},{"v":25,"t":"‌ای پدر عادل، جهان تو را نشناخت، اما من تو راشناختم؛ و اینها شناخته‌اند که تو مرا فرستادی."},{"v":26,"t":"و اسم تو را به ایشان شناسانیدم و خواهم شناسانید تا آن محبتی که به من نموده‌ای در ایشان باشد و من نیز در ایشان باشم.»"}],"en":[{"v":1,"t":"Jesus said these things, then lifting up his eyes to heaven, he said, “Father, the time has come. Glorify your Son, that your Son may also glorify you;"},{"v":2,"t":"even as you gave him authority over all flesh, so he will give eternal life to all whom you have given him."},{"v":3,"t":"This is eternal life, that they should know you, the only true God, and him whom you sent, Jesus Christ."},{"v":4,"t":"I glorified you on the earth. I have accomplished the work which you have given me to do."},{"v":5,"t":"Now, Father, glorify me with your own self with the glory which I had with you before the world existed."},{"v":6,"t":"“I revealed your name to the people whom you have given me out of the world. They were yours, and you have given them to me. They have kept your word."},{"v":7,"t":"Now they have known that all things whatever you have given me are from you,"},{"v":8,"t":"for the words which you have given me I have given to them; and they received them, and knew for sure that I came from you. They have believed that you sent me."},{"v":9,"t":"I pray for them. I don’t pray for the world, but for those whom you have given me, for they are yours."},{"v":10,"t":"All things that are mine are yours, and yours are mine, and I am glorified in them."},{"v":11,"t":"I am no more in the world, but these are in the world, and I am coming to you. Holy Father, keep them through your name which you have given me, that they may be one, even as we are."},{"v":12,"t":"While I was with them in the world, I kept them in your name. I have kept those whom you have given me. None of them is lost except the son of destruction, that the Scripture might be fulfilled."},{"v":13,"t":"But now I come to you, and I say these things in the world, that they may have my joy made full in themselves."},{"v":14,"t":"I have given them your word. The world hated them because they are not of the world, even as I am not of the world."},{"v":15,"t":"I pray not that you would take them from the world, but that you would keep them from the evil one."},{"v":16,"t":"They are not of the world, even as I am not of the world."},{"v":17,"t":"Sanctify them in your truth. Your word is truth."},{"v":18,"t":"As you sent me into the world, even so I have sent them into the world."},{"v":19,"t":"For their sakes I sanctify myself, that they themselves also may be sanctified in truth."},{"v":20,"t":"“Not for these only do I pray, but for those also who will believe in me through their word,"},{"v":21,"t":"that they may all be one; even as you, Father, are in me, and I in you, that they also may be one in us; that the world may believe that you sent me."},{"v":22,"t":"The glory which you have given me, I have given to them, that they may be one, even as we are one,"},{"v":23,"t":"I in them, and you in me, that they may be perfected into one, that the world may know that you sent me and loved them, even as you loved me."},{"v":24,"t":"Father, I desire that they also whom you have given me be with me where I am, that they may see my glory which you have given me, for you loved me before the foundation of the world."},{"v":25,"t":"Righteous Father, the world hasn’t known you, but I knew you; and these knew that you sent me."},{"v":26,"t":"I made known to them your name, and will make it known; that the love with which you loved me may be in them, and I in them.”"}],"hr":[{"v":1,"t":"To Isus doreče, a onda podiže oči k nebu i progovori: “Oče, došao je čas: proslavi Sina svoga da Sin proslavi tebe"},{"v":2,"t":"i da vlašću koju si mu dao nad svakim tijelom dade život vječni svima koje si mu dao."},{"v":3,"t":"A ovo je život vječni: da upoznaju tebe, jedinoga istinskog Boga, i koga si poslao - Isusa Krista."},{"v":4,"t":"Ja tebe proslavih na zemlji dovršivši djelo koje si mi dao izvršiti."},{"v":5,"t":"A sada ti, Oče, proslavi mene kod sebe onom slavom koju imadoh kod tebe prije negoli je svijeta bilo."},{"v":6,"t":"Objavio sam ime tvoje ljudima koje si mi dao od svijeta. Tvoji bijahu, a ti ih meni dade i riječ su tvoju sačuvali."},{"v":7,"t":"Sad upoznaše da je od tebe sve što si mi dao"},{"v":8,"t":"jer riječi koje si mi dao njima predadoh i oni ih primiše i uistinu spoznaše da sam od tebe izišao te povjerovaše da si me ti poslao."},{"v":9,"t":"Ja za njih molim; ne molim za svijet, nego za one koje si mi dao jer su tvoji."},{"v":10,"t":"I sve moje tvoje je, i tvoje moje, i ja se proslavih u njima."},{"v":11,"t":"Ja više nisam u svijetu, no oni su u svijetu, a ja idem k tebi. Oče sveti, sačuvaj ih u svom imenu koje si mi dao: da budu jedno kao i mi."},{"v":12,"t":"Dok sam ja bio s njima, ja sam ih čuvao u tvom imenu, njih koje si mi dao; i štitio ih, te nijedan od njih ne propade osim sina propasti, da se Pismo ispuni."},{"v":13,"t":"A sada k tebi idem i ovo govorim u svijetu da imaju puninu moje radosti u sebi."},{"v":14,"t":"Ja sam im predao tvoju riječ, a svijet ih zamrzi jer nisu od svijeta kao što ni ja nisam od svijeta."},{"v":15,"t":"Ne molim te da ih uzmeš sa svijeta, nego da ih očuvaš od Zloga."},{"v":16,"t":"Oni nisu od svijeta kao što ni ja nisam od svijeta."},{"v":17,"t":"Posveti ih u istini: tvoja je riječ istina."},{"v":18,"t":"Kao što ti mene posla u svijet tako i ja poslah njih u svijet."},{"v":19,"t":"I za njih posvećujem samog sebe da i oni budu posvećeni u istini."},{"v":20,"t":"Ne molim samo za ove nego i za one koji će na njihovu riječ vjerovati u mene:"},{"v":21,"t":"da svi budu jedno kao što ti, Oče, u meni i ja u tebi, neka i oni u nama budu da svijet uzvjeruje da si me ti poslao."},{"v":22,"t":"I slavu koju si ti dao meni ja dadoh njima: da budu jedno kao što smo mi jedno -"},{"v":23,"t":"ja u njima i ti u meni, da tako budu savršeno jedno da svijet upozna da si me ti poslao i ljubio njih kao što si mene ljubio."},{"v":24,"t":"Oče, hoću da i oni koje si mi dao budu gdje sam ja, da i oni budu sa mnom: da gledaju moju slavu, slavu koju si mi dao jer si me ljubio prije postanka svijeta."},{"v":25,"t":"Oče pravedni, svijet te nije upoznao, ja te upoznah; a i ovi upoznaše da si me ti poslao."},{"v":26,"t":"I njima sam očitovao tvoje ime, i još ću očitovati, da ljubav kojom si ti mene ljubio bude u njima - i ja u njima.”"}]},"18":{"fa":[{"v":1,"t":"چون عیسی این را گفت، با شاگردان خود به آن طرف وادی قدرون رفت ودر آنجا باغی بود که با شاگردان خود به آن درآمد."},{"v":2,"t":"و یهودا که تسلیم‌کننده وی بود، آن موضع را می‌دانست، چونکه عیسی در آنجا با شاگردان خود بارها انجمن می‌نمود."},{"v":3,"t":"پس یهودا لشکریان و خادمان از نزد روسای کهنه و فریسیان برداشته، با چراغها و مشعلها و اسلحه به آنجا آمد."},{"v":4,"t":"آنگاه عیسی با اینکه آگاه بود از آنچه می‌بایست بر اوواقع شود، بیرون آمده، به ایشان گفت: «که رامی طلبید؟»"},{"v":5,"t":"به او جواب دادند: «عیسی ناصری را!» عیسی بدیشان گفت: «من هستم!» و یهودا که تسلیم‌کننده او بود نیز با ایشان ایستاده بود."},{"v":6,"t":"پس چون بدیشان گفت: «من هستم، » برگشته، بر زمین افتادند."},{"v":7,"t":"او باز از ایشان سوال کرد: «که را می طلبید؟» گفتند: «عیسی ناصری را!»"},{"v":8,"t":"عیسی جواب داد: «به شما گفتم من هستم. پس اگر مرامی خواهید، اینها را بگذارید بروند.»"},{"v":9,"t":"تا آن سخنی که گفته بود تمام گردد که «از آنانی که به من داده‌ای یکی را گم نکرده‌ام.»"},{"v":10,"t":"آنگاه شمعون پطرس شمشیری که داشت کشیده، به غلام رئیس کهنه که ملوک نام داشت زده، گوش راستش را برید."},{"v":11,"t":"عیسی به پطرس گفت: «شمشیر خود را غلاف کن. آیا جامی را که پدر به من داده است ننوشم؟»"},{"v":12,"t":"انگاه سربازان و سرتیبان و خادمان یهود، عیسی را گرفته، او را بستند."},{"v":13,"t":"و اول او را نزدحنا، پدر زن قیافا که در همان سال رئیس کهنه بود، آوردند."},{"v":14,"t":"و قیافا همان بود که به یهود اشاره کرده بود که «بهتر است یک شخص در راه قوم بمیرد.»"},{"v":15,"t":"اما شمعون پطرس و شاگردی دیگر ازعقب عیسی روانه شدند، و چون آن شاگرد نزدرئیس کهنه معروف بود، با عیسی داخل خانه رئیس کهنه شد."},{"v":16,"t":"اما پطرس بیرون در ایستاده بود. پس آن شاگرد دیگر که آشنای رئیس کهنه بود، بیرون آمده، با دربان گفتگو کرد و پطرس را به اندرون برد."},{"v":17,"t":"آنگاه آن کنیزی که دربان بود، به پطرس گفت: «آیا تو نیز از شاگردان این شخص نیستی؟» گفت: «نیستم.»"},{"v":18,"t":"و غلامان و خدام آتش افروخته، ایستاده بودند و خود را گرم می‌کردند چونکه هوا سرد بود؛ و پطرس نیز باایشان خود را گرم می‌کرد."},{"v":19,"t":"پس رئیس کهنه از عیسی درباره شاگردان و تعلیم او پرسید."},{"v":20,"t":"عیسی به او جواب داد که «من به جهان آشکارا سخن گفته‌ام. من هر وقت درکنیسه و در هیکل، جایی که همه یهودیان پیوسته جمع می‌شدند، تعلیم می‌دادم و در خفا چیزی نگفته‌ام."},{"v":21,"t":"چرا از من سوال می‌کنی؟ از کسانی که شنیده‌اند بپرس که چه چیز بدیشان گفتم. اینک ایشان می‌دانند آنچه من گفتم.»"},{"v":22,"t":"و چون این راگفت، یکی از خادمان که در آنجا ایستاده بود، طپانچه بر عیسی زده، گفت: «آیا به رئیس کهنه چنین جواب می‌دهی؟»"},{"v":23,"t":"عیسی بدو جواب داد: «اگر بد گفتم، به بدی شهادت ده؛ و اگرخوب، برای چه مرا می‌زنی؟»"},{"v":24,"t":"پس حنا او رابسته، به نزد قیافا رئیس کهنه فرستاد."},{"v":25,"t":"و شمعون پطرس ایستاده، خود را گرم می‌کرد. بعضی بدو گفتند: «آیا تو نیز از شاگردان او نیستی؟» او انکار کرده، گفت: «نیستم!»"},{"v":26,"t":"پس یکی از غلامان رئیس کهنه که از خویشان آن کس بود که پطرس گوشش را بریده بود، گفت: «مگرمن تو را با او در باغ ندیدم؟»"},{"v":27,"t":"پطرس باز انکارکرد که در حال خروس بانگ زد."},{"v":28,"t":"بعد عیسی را از نزد قیافا به دیوانخانه آوردند و صبح بود و ایشان داخل دیوانخانه نشدند مبادا نجس بشوند بلکه تا فصح را بخورند."},{"v":29,"t":"پس پیلاطس به نزد ایشان بیرون آمده، گفت: «چه دعوی بر این شخص دارید؟»"},{"v":30,"t":"در جواب او گفتند: «اگر او بدکار نمی بود، به تو تسلیم نمی کردیم.»"},{"v":31,"t":"پیلاطس بدیشان گفت: «شما اورا بگیرید و موافق شریعت خود بر او حکم نمایید.» یهودیان به وی گفتند: «بر ما جایز نیست که کسی را بکشیم.»"},{"v":32,"t":"تا قول عیسی تمام گرددکه گفته بود، اشاره به آن قسم موت که باید بمیرد."},{"v":33,"t":"پس پیلاطس باز داخل دیوانخانه شد وعیسی را طلبیده، به او گفت: «آیا تو پادشاه یهودهستی؟»"},{"v":34,"t":"عیسی به او جواب داد: «آیا تو این رااز خود می‌گویی یا دیگران درباره من به توگفتند؟»"},{"v":35,"t":"پیلاطس جواب داد: «مگر من یهودهستم؟ امت تو و روسای کهنه تو را به من تسلیم کردند. چه کرده‌ای؟»"},{"v":36,"t":"عیسی جواب داد که «پادشاهی من از این جهان نیست. اگر پادشاهی من از این جهان می‌بود، خدام من جنگ می‌کردند تا به یهود تسلیم نشوم. لیکن اکنون پادشاهی من از این جهان نیست.»"},{"v":37,"t":"پیلاطس به او گفت: «مگر توپادشاه هستی؟» عیسی جواب داد: «تو می‌گویی که من پادشاه هستم. از این جهت من متولد شدم وبجهت این در جهان آمدم تا به راستی شهادت دهم، و هر‌که از راستی است سخن مرا می‌شنود.»"},{"v":38,"t":"پیلاطس به او گفت: «راستی چیست؟» و چون این را بگفت، باز به نزد یهودیان بیرون شده، به ایشان گفت: «من در این شخص هیچ عیبی نیافتم."},{"v":39,"t":"و قانون شما این است که در عید فصح بجهت شما یک نفر آزاد کنم. پس آیا می‌خواهید بجهت شما پادشاه یهود را آزاد کنم؟»"},{"v":40,"t":"باز همه فریاد برآورده، گفتند: «او را نی بلکه برابا را.» وبرابا دزد بود."}],"en":[{"v":1,"t":"When Jesus had spoken these words, he went out with his disciples over the brook Kidron, where there was a garden, into which he and his disciples entered."},{"v":2,"t":"Now Judas, who betrayed him, also knew the place, for Jesus often met there with his disciples."},{"v":3,"t":"Judas then, having taken a detachment of soldiers and officers from the chief priests and the Pharisees, came there with lanterns, torches, and weapons."},{"v":4,"t":"Jesus therefore, knowing all the things that were happening to him, went out and said to them, “Who are you looking for?”"},{"v":5,"t":"They answered him, “Jesus of Nazareth.” Jesus said to them, “I am he.” Judas also, who betrayed him, was standing with them."},{"v":6,"t":"When therefore he said to them, “I am he,” they went backward and fell to the ground."},{"v":7,"t":"Again therefore he asked them, “Who are you looking for?” They said, “Jesus of Nazareth.”"},{"v":8,"t":"Jesus answered, “I told you that I am he. If therefore you seek me, let these go their way,”"},{"v":9,"t":"that the word might be fulfilled which he spoke, “Of those whom you have given me, I have lost none.”"},{"v":10,"t":"Simon Peter therefore, having a sword, drew it, struck the high priest’s servant, and cut off his right ear. The servant’s name was Malchus."},{"v":11,"t":"Jesus therefore said to Peter, “Put the sword into its sheath. The cup which the Father has given me, shall I not surely drink it?”"},{"v":12,"t":"So the detachment, the commanding officer, and the officers of the Jews seized Jesus and bound him,"},{"v":13,"t":"and led him to Annas first, for he was father-in-law to Caiaphas, who was high priest that year."},{"v":14,"t":"Now it was Caiaphas who advised the Jews that it was expedient that one man should perish for the people."},{"v":15,"t":"Simon Peter followed Jesus, as did another disciple. Now that disciple was known to the high priest, and entered in with Jesus into the court of the high priest;"},{"v":16,"t":"but Peter was standing at the door outside. So the other disciple, who was known to the high priest, went out and spoke to her who kept the door, and brought in Peter."},{"v":17,"t":"Then the maid who kept the door said to Peter, “Are you also one of this man’s disciples?” He said, “I am not.”"},{"v":18,"t":"Now the servants and the officers were standing there, having made a fire of coals, for it was cold. They were warming themselves. Peter was with them, standing and warming himself."},{"v":19,"t":"The high priest therefore asked Jesus about his disciples and about his teaching."},{"v":20,"t":"Jesus answered him, “I spoke openly to the world. I always taught in synagogues and in the temple, where the Jews always meet. I said nothing in secret."},{"v":21,"t":"Why do you ask me? Ask those who have heard me what I said to them. Behold, they know the things which I said.”"},{"v":22,"t":"When he had said this, one of the officers standing by slapped Jesus with his hand, saying, “Do you answer the high priest like that?”"},{"v":23,"t":"Jesus answered him, “If I have spoken evil, testify of the evil; but if well, why do you beat me?”"},{"v":24,"t":"Annas sent him bound to Caiaphas, the high priest."},{"v":25,"t":"Now Simon Peter was standing and warming himself. They said therefore to him, “You aren’t also one of his disciples, are you?” He denied it and said, “I am not.”"},{"v":26,"t":"One of the servants of the high priest, being a relative of him whose ear Peter had cut off, said, “Didn’t I see you in the garden with him?”"},{"v":27,"t":"Peter therefore denied it again, and immediately the rooster crowed."},{"v":28,"t":"They led Jesus therefore from Caiaphas into the Praetorium. It was early, and they themselves didn’t enter into the Praetorium, that they might not be defiled, but might eat the Passover."},{"v":29,"t":"Pilate therefore went out to them and said, “What accusation do you bring against this man?”"},{"v":30,"t":"They answered him, “If this man weren’t an evildoer, we wouldn’t have delivered him up to you.”"},{"v":31,"t":"Pilate therefore said to them, “Take him yourselves, and judge him according to your law.” Therefore the Jews said to him, “It is illegal for us to put anyone to death,”"},{"v":32,"t":"that the word of Jesus might be fulfilled, which he spoke, signifying by what kind of death he should die."},{"v":33,"t":"Pilate therefore entered again into the Praetorium, called Jesus, and said to him, “Are you the King of the Jews?”"},{"v":34,"t":"Jesus answered him, “Do you say this by yourself, or did others tell you about me?”"},{"v":35,"t":"Pilate answered, “I’m not a Jew, am I? Your own nation and the chief priests delivered you to me. What have you done?”"},{"v":36,"t":"Jesus answered, “My Kingdom is not of this world. If my Kingdom were of this world, then my servants would fight, that I wouldn’t be delivered to the Jews. But now my Kingdom is not from here.”"},{"v":37,"t":"Pilate therefore said to him, “Are you a king then?” Jesus answered, “You say that I am a king. For this reason I have been born, and for this reason I have come into the world, that I should testify to the truth. Everyone who is of the truth listens to my voice.”"},{"v":38,"t":"Pilate said to him, “What is truth?” When he had said this, he went out again to the Jews, and said to them, “I find no basis for a charge against him."},{"v":39,"t":"But you have a custom that I should release someone to you at the Passover. Therefore, do you want me to release to you the King of the Jews?”"},{"v":40,"t":"Then they all shouted again, saying, “Not this man, but Barabbas!” Now Barabbas was a robber."}],"hr":[{"v":1,"t":"To rekavši, zaputi se Isus sa svojim učenicima na drugu stranu potoka Cedrona. Ondje bijaše vrt u koji uđe Isus i njegovi učenici."},{"v":2,"t":"A poznavaše to mjesto i Juda, njegov izdajica, jer se Isus tu često sastajao sa svojim učenicima."},{"v":3,"t":"Juda onda uze četu i od svećeničkih glavara i farizeja sluge te dođe onamo sa zubljama, svjetiljkama i oružjem."},{"v":4,"t":"Znajući sve što će s njim biti, istupi Isus naprijed te ih upita: “Koga tražite?”"},{"v":5,"t":"Odgovore mu: “Isusa Nazarećanina.” Reče im Isus: “Ja sam!” A stajaše s njima i Juda, njegov izdajica."},{"v":6,"t":"Kad im dakle reče: “Ja sam!” - oni ustuknuše i popadaše na zemlju."},{"v":7,"t":"Ponovno ih tada upita: “Koga tražite?” Oni odgovore: “Isusa Nazarećanina.”"},{"v":8,"t":"Isus odvrati: “Rekoh vam da sam ja. Ako dakle mene tražite, pustite ove da odu” -"},{"v":9,"t":"da se ispuni riječ koju reče: “Ne izgubih ni jednoga od onih koje si mi dao.”"},{"v":10,"t":"A Šimun Petar isuče mač koji je imao uza se pa udari slugu velikoga svećenika i odsiječe mu desno uho. Sluga se zvao Malho."},{"v":11,"t":"Nato Isus reče Petru: “Djeni mač u korice! Čašu koju mi dade Otac zar da ne pijem?”"},{"v":12,"t":"Tada četa, zapovjednik i židovski sluge uhvatiše Isusa te ga svezaše."},{"v":13,"t":"Odvedoše ga najprije Ani jer on bijaše tast Kajfe, velikoga svećenika one godine."},{"v":14,"t":"Kajfa pak ono svjetova Židove: “Bolje da jedan čovjek umre za narod.”"},{"v":15,"t":"Za Isusom su išli Šimun Petar i drugi učenik. Taj učenik bijaše poznat s velikim svećenikom pa s Isusom uđe u dvorište velikoga svećenika."},{"v":16,"t":"Petar osta vani kod vrata. Tada taj drugi učenik, znanac velikoga svećenika, iziđe i reče vratarici te uvede Petra."},{"v":17,"t":"Nato će sluškinja, vratarica, Petru: “Da nisi i ti od učenika toga čovjeka?” On odvrati: “Nisam!”"},{"v":18,"t":"A stajahu ondje sluge i stražari, raspirivahu žeravicu jer bijaše studeno i grijahu se. S njima je stajao i Petar i grijao se."},{"v":19,"t":"Veliki svećenik zapita Isusa o njegovim učenicima i o njegovu nauku."},{"v":20,"t":"Odgovori mu Isus: “Ja sam javno govorio svijetu. Uvijek sam naučavao u sinagogi i u Hramu gdje se skupljaju svi Židovi. Ništa nisam u tajnosti govorio."},{"v":21,"t":"Zašto mene pitaš? Pitaj one koji su slušali što sam im govorio. Oni eto znaju što sam govorio.”"},{"v":22,"t":"Na te njegove riječi jedan od nazočnih slugu pljusne Isusa govoreći: “Tako li odgovaraš velikom svećeniku?”"},{"v":23,"t":"Odgovori mu Isus: “Ako sam krivo rekao, dokaži da je krivo! Ako li pravo, zašto me udaraš?”"},{"v":24,"t":"Ana ga zatim posla svezana Kajfi, velikom svećeniku."},{"v":25,"t":"Šimun Petar stajao je ondje i grijao se. Rekoše mu: “Da nisi i ti od njegovih učenika?” On zanijeka: “Nisam!”"},{"v":26,"t":"Nato će jedan od slugu velikog svećenika, rođak onoga komu je Petar bio odsjekao uho: “Nisam li te ja vidio u vrtu s njime?”"},{"v":27,"t":"I Petar opet zanijeka, a pijetao odmah zapjeva."},{"v":28,"t":"Nato odvedoše Isusa od Kajfe u dvor upraviteljev. Bilo je rano jutro. I oni ne uđoše da se ne okaljaju, već da mognu blagovati pashu."},{"v":29,"t":"Pilat tada iziđe pred njih i upita: “Kakvu tužbu iznosite protiv ovoga čovjeka?”"},{"v":30,"t":"Odgovore mu: “Kad on ne bi bio zločinac, ne bismo ga predali tebi.”"},{"v":31,"t":"Reče im nato Pilat: “Uzmite ga vi i sudite mu po svom zakonu.” Odgovoriše mu Židovi: “Nama nije dopušteno nikoga pogubiti” -"},{"v":32,"t":"da se ispuni riječ Isusova kojom je označio kakvom mu je smrću umrijeti."},{"v":33,"t":"Nato Pilat uđe opet u dvor, pozove Isusa i upita ga: “Ti li si židovski kralj?”"},{"v":34,"t":"Isus odgovori: “Govoriš li ti to sam od sebe ili ti to drugi rekoše o meni?”"},{"v":35,"t":"Pilat odvrati: “Zar sam ja Židov? Tvoj narod i glavari svećenički predadoše te meni. Što si učinio?”"},{"v":36,"t":"Odgovori Isus: “Kraljevstvo moje nije od ovoga svijeta. Kad bi moje kraljevstvo bilo od ovoga svijeta, moje bi se sluge borile da ne budem predan Židovima. Ali kraljevstvo moje nije odavde.”"},{"v":37,"t":"Nato mu reče Pilat: “Ti si dakle kralj?” Isus odgovori: “Ti kažeš: ja sam kralj. Ja sam se zato rodio i došao na svijet da svjedočim za istinu. Tko je god od istine, sluša moj glas.”"},{"v":38,"t":"Reče mu Pilat: “Što je istina?”"},{"v":39,"t":"Rekavši to, opet iziđe pred Židove i reče im: “Ja ne nalazim na njemu nikakve krivice. A u vas je običaj da vam o Pashi nekoga pustim. Hoćete li dakle da vam pustim kralja židovskoga?”"},{"v":40,"t":"Povikaše nato opet: “Ne toga, nego Barabu!” A Baraba bijaše razbojnik."}]},"19":{"fa":[{"v":1,"t":"پس پیلاطس عیسی را گرفته، تازیانه زد."},{"v":2,"t":"و لشکریان تاجی از خار بافته برسرش گذاردند و جامه ارغوانی بدو پوشانیدند"},{"v":3,"t":"ومی گفتند: «سلام‌ای پادشاه یهود!» و طپانچه بدومی زدند."},{"v":4,"t":"باز پیلاطس بیرون آمده، به ایشان گفت: «اینک او را نزد شما بیرون آوردم تا بدانیدکه در او هیچ عیبی نیافتم.»"},{"v":5,"t":"آنگاه عیسی با تاجی از خار و لباس ارغوانی بیرون آمد. پیلاطس بدیشان گفت: «اینک آن انسان.»"},{"v":6,"t":"و چون روسای کهنه و خدام او را دیدند، فریاد برآورده، گفتند: «صلیبش کن! صلیبش کن!» پیلاطس بدیشان گفت: «شما او را گرفته، مصلوبش سازید زیرا که من در او عیبی نیافتم.»"},{"v":7,"t":"یهودیان بدو جواب دادند که «ما شریعتی داریم و موافق شریعت ماواجب است که بمیرد زیرا خود را پسر خداساخته است.»"},{"v":8,"t":"پس چون پیلاطس این را شنید، خوف بر اوزیاده مستولی گشت."},{"v":9,"t":"باز داخل دیوانخانه شده، به عیسی گفت: «تو از کجایی؟» اما عیسی بدوهیچ جواب نداد."},{"v":10,"t":"پیلاطس بدو گفت: «آیا به من سخن نمی گویی؟ نمی دانی که قدرت دارم تو راصلیب کنم و قدرت دارم آزادت نمایم؟»"},{"v":11,"t":"عیسی جواب داد: «هیچ قدرت بر من نمی داشتی اگر از بالا به تو داده نمی شد. و از این جهت آن کس که مرا به تو تسلیم کرد، گناه بزرگتردارد.»"},{"v":12,"t":"و از آن وقت پیلاطس خواست او راآزاد نماید، لیکن یهودیان فریاد برآورده، می‌گفتند که «اگر این شخص را رها کنی، دوست قیصر نیستی. هر‌که خود را پادشاه سازد، برخلاف قیصر سخن گوید.»"},{"v":13,"t":"پس چون پیلاطس این را شنید، عیسی رابیرون آورده، بر مسند حکومت، در موضعی که به بلاط و به عبرانی جباتا گفته می‌شد، نشست."},{"v":14,"t":"ووقت تهیه فصح و قریب به ساعت ششم بود. پس به یهودیان گفت: «اینک پادشاه شما.»"},{"v":15,"t":"ایشان فریاد زدند: «او را بر دار، بر دار! صلیبش کن!» پیلاطس به ایشان گفت: «آیا پادشاه شما رامصلوب کنم؟» روسای کهنه جواب دادند که «غیر از قیصر پادشاهی نداریم.»"},{"v":16,"t":"آنگاه او را بدیشان تسلیم کرد تا مصلوب شود. پس عیسی را گرفته بردند"},{"v":17,"t":"و صلیب خودرا برداشته، بیرون رفت به موضعی که به جمجمه مسمی بود و به عبرانی آن را جلجتا می‌گفتند."},{"v":18,"t":"او را در آنجا صلیب نمودند و دو نفر دیگررا از این طرف و آن طرف و عیسی را در میان."},{"v":19,"t":"وپیلاطس تقصیرنامه‌ای نوشته، بر صلیب گذارد؛ ونوشته این بود: «عیسی ناصری پادشاه یهود.»"},{"v":20,"t":"واین تقصیر نامه را بسیاری از یهود خواندند، زیراآن مکانی که عیسی را صلیب کردند، نزدیک شهربود و آن را به زبان عبرانی و یونانی و لاتینی نوشته بودند."},{"v":21,"t":"پس روسای کهنه یهود به پیلاطس گفتند: «منویس پادشاه یهود، بلکه که او گفت منم پادشاه یهود.»"},{"v":22,"t":"پیلاطس جواب داد: «آنچه نوشتم، نوشتم.»"},{"v":23,"t":"پس لشکریان چون عیسی را صلیب کردند، جامه های او را برداشته، چهار قسمت کردند، هرسپاهی را یک قسمت؛ و پیراهن را نیز، اما پیراهن درز نداشت، بلکه تمام از بالا بافته شده بود."},{"v":24,"t":"پس به یکدیگر گفتند: «این را پاره نکنیم، بلکه قرعه بر آن بیندازیم تا از آن که شود.» تا تمام گردد کتاب که می‌گوید: «در میان خود جامه های مرا تقسیم کردند و بر لباس من قرعه افکندند.» پس لشکریان چنین کردند."},{"v":25,"t":"و پای صلیب عیسی، مادر او و خواهر مادرش مریم زن، کلوپا ومریم مجدلیه ایستاده بودند."},{"v":26,"t":"چون عیسی مادرخود را با آن شاگردی که دوست می‌داشت ایستاده دید، به مادر خود گفت: «ای زن، اینک پسر تو.»"},{"v":27,"t":"و به آن شاگرد گفت: «اینک مادر تو.» و در همان ساعت آن شاگرد او را به خانه خودبرد."},{"v":28,"t":"و بعد چون عیسی دید که همه‌چیز به انجام رسیده است تا کتاب تمام شود، گفت: «تشنه‌ام.»"},{"v":29,"t":"و در آنجا ظرفی پر از سرکه گذارده بود. پس اسفنجی را از سرکه پر ساخته، و بر زوفا گذارده، نزدیک دهان او بردند."},{"v":30,"t":"چون عیسی سرکه راگرفت، گفت: «تمام شد.» و سر خود را پایین آورده، جان بداد."},{"v":31,"t":"پس یهودیان تا بدنها در روز سبت برصلیب نماند، چونکه روز تهیه بود و آن سبت، روز بزرگ بود، از پیلاطس درخواست کردند که ساق پایهای ایشان را بشکنند و پایین بیاورند."},{"v":32,"t":"آنگاه لشکریان آمدند و ساقهای آن اول ودیگری را که با او صلیب شده بودند، شکستند."},{"v":33,"t":"اما چون نزد عیسی آمدند و دیدند که پیش ازآن مرده است، ساقهای او را نشکستند."},{"v":34,"t":"لکن یکی از لشکریان به پهلوی او نیزه‌ای زد که در آن ساعت خون و آب بیرون آمد."},{"v":35,"t":"و آن کسی‌که دید شهادت داد و شهادت او راست است و اومی داند که راست می‌گوید تا شما نیز ایمان آورید."},{"v":36,"t":"زیرا که این واقع شد تا کتاب تمام شودکه می‌گوید: «استخوانی از او شکسته نخواهدشد.»"},{"v":37,"t":"و باز کتاب دیگر می‌گوید: «آن کسی راکه نیزه زدند خواهند نگریست.»"},{"v":38,"t":"و بعد از این، یوسف که از اهل رامه وشاگرد عیسی بود، لیکن مخفی به‌سبب ترس یهود، از پیلاطس خواهش کرد که جسد عیسی رابردارد. پیلاطس اذن داد. پس آمده، بدن عیسی رابرداشت."},{"v":39,"t":"و نیقودیموس نیز که اول در شب نزدعیسی آمده بود، مر مخلوط با عود قریب به صدرطل با خود آورد."},{"v":40,"t":"آنگاه بدن عیسی را بداشته، در کفن با حنوط به رسم تکفین یهود پیچیدند."},{"v":41,"t":"و در موضعی که مصلوب شد باغی بود و درباغ، قبر تازه‌ای که هرگز هیچ‌کس در آن دفن نشده بود."},{"v":42,"t":"پس به‌سبب تهیه یهود، عیسی را در آنجاگذاردند، چونکه آن قبر نزدیک بود."}],"en":[{"v":1,"t":"So Pilate then took Jesus and flogged him."},{"v":2,"t":"The soldiers twisted thorns into a crown and put it on his head, and dressed him in a purple garment."},{"v":3,"t":"They kept saying, “Hail, King of the Jews!” and they kept slapping him."},{"v":4,"t":"Then Pilate went out again, and said to them, “Behold, I bring him out to you, that you may know that I find no basis for a charge against him.”"},{"v":5,"t":"Jesus therefore came out, wearing the crown of thorns and the purple garment. Pilate said to them, “Behold, the man!”"},{"v":6,"t":"When therefore the chief priests and the officers saw him, they shouted, saying, “Crucify! Crucify!” Pilate said to them, “Take him yourselves and crucify him, for I find no basis for a charge against him.”"},{"v":7,"t":"The Jews answered him, “We have a law, and by our law he ought to die, because he made himself the Son of God.”"},{"v":8,"t":"When therefore Pilate heard this saying, he was more afraid."},{"v":9,"t":"He entered into the Praetorium again, and said to Jesus, “Where are you from?” But Jesus gave him no answer."},{"v":10,"t":"Pilate therefore said to him, “Aren’t you speaking to me? Don’t you know that I have power to release you and have power to crucify you?”"},{"v":11,"t":"Jesus answered, “You would have no power at all against me, unless it were given to you from above. Therefore he who delivered me to you has greater sin.”"},{"v":12,"t":"At this, Pilate was seeking to release him, but the Jews cried out, saying, “If you release this man, you aren’t Caesar’s friend! Everyone who makes himself a king speaks against Caesar!”"},{"v":13,"t":"When Pilate therefore heard these words, he brought Jesus out and sat down on the judgment seat at a place called “The Pavement”, but in Hebrew, “Gabbatha.”"},{"v":14,"t":"Now it was the Preparation Day of the Passover, at about the sixth hour. He said to the Jews, “Behold, your King!”"},{"v":15,"t":"They cried out, “Away with him! Away with him! Crucify him!” Pilate said to them, “Shall I crucify your King?” The chief priests answered, “We have no king but Caesar!”"},{"v":16,"t":"So then he delivered him to them to be crucified. So they took Jesus and led him away."},{"v":17,"t":"He went out, bearing his cross, to the place called “The Place of a Skull”, which is called in Hebrew, “Golgotha”,"},{"v":18,"t":"where they crucified him, and with him two others, on either side one, and Jesus in the middle."},{"v":19,"t":"Pilate wrote a title also, and put it on the cross. There was written, “JESUS OF NAZARETH, THE KING OF THE JEWS.”"},{"v":20,"t":"Therefore many of the Jews read this title, for the place where Jesus was crucified was near the city; and it was written in Hebrew, in Latin, and in Greek."},{"v":21,"t":"The chief priests of the Jews therefore said to Pilate, “Don’t write, ‘The King of the Jews,’ but, ‘he said, “I am King of the Jews.”’”"},{"v":22,"t":"Pilate answered, “What I have written, I have written.”"},{"v":23,"t":"Then the soldiers, when they had crucified Jesus, took his garments and made four parts, to every soldier a part; and also the tunic. Now the tunic was without seam, woven from the top throughout."},{"v":24,"t":"Then they said to one another, “Let’s not tear it, but cast lots for it to decide whose it will be,” that the Scripture might be fulfilled, which says, “They parted my garments among them. They cast lots for my clothing.” Therefore the soldiers did these things."},{"v":25,"t":"But standing by Jesus’ cross were his mother, his mother’s sister, Mary the wife of Clopas, and Mary Magdalene."},{"v":26,"t":"Therefore when Jesus saw his mother, and the disciple whom he loved standing there, he said to his mother, “Woman, behold, your son!”"},{"v":27,"t":"Then he said to the disciple, “Behold, your mother!” From that hour, the disciple took her to his own home."},{"v":28,"t":"After this, Jesus, seeing that all things were now finished, that the Scripture might be fulfilled, said, “I am thirsty!”"},{"v":29,"t":"Now a vessel full of vinegar was set there; so they put a sponge full of the vinegar on hyssop, and held it at his mouth."},{"v":30,"t":"When Jesus therefore had received the vinegar, he said, “It is finished!” Then he bowed his head and gave up his spirit."},{"v":31,"t":"Therefore the Jews, because it was the Preparation Day, so that the bodies wouldn’t remain on the cross on the Sabbath (for that Sabbath was a special one), asked of Pilate that their legs might be broken and that they might be taken away."},{"v":32,"t":"Therefore the soldiers came and broke the legs of the first and of the other who was crucified with him;"},{"v":33,"t":"but when they came to Jesus and saw that he was already dead, they didn’t break his legs."},{"v":34,"t":"However, one of the soldiers pierced his side with a spear, and immediately blood and water came out."},{"v":35,"t":"He who has seen has testified, and his testimony is true. He knows that he tells the truth, that you may believe."},{"v":36,"t":"For these things happened that the Scripture might be fulfilled, “A bone of him will not be broken.”"},{"v":37,"t":"Again another Scripture says, “They will look on him whom they pierced.”"},{"v":38,"t":"After these things, Joseph of Arimathaea, being a disciple of Jesus, but secretly for fear of the Jews, asked of Pilate that he might take away Jesus’ body. Pilate gave him permission. He came therefore and took away his body."},{"v":39,"t":"Nicodemus, who at first came to Jesus by night, also came bringing a mixture of myrrh and aloes, about a hundred Roman pounds."},{"v":40,"t":"So they took Jesus’ body, and bound it in linen cloths with the spices, as the custom of the Jews is to bury."},{"v":41,"t":"Now in the place where he was crucified there was a garden. In the garden was a new tomb in which no man had ever yet been laid."},{"v":42,"t":"Then, because of the Jews’ Preparation Day (for the tomb was near at hand), they laid Jesus there."}],"hr":[{"v":1,"t":"Tada Pilat uze i izbičeva Isusa."},{"v":2,"t":"A vojnici spletoše vijenac od trnja i staviše mu ga na glavu; i zaogrnuše ga grimiznim plaštem."},{"v":3,"t":"I prilazili su mu i govorili: “Zdravo kralju židovski!” I pljuskali su ga."},{"v":4,"t":"A Pilat ponovno iziđe i reče im: “Evo vam ga izvodim da znate: ne nalazim na njemu nikakve krivice.”"},{"v":5,"t":"Iziđe tada Isus s trnovim vijencem, u grimiznom plaštu. A Pilat im kaže: “Evo čovjeka!”"},{"v":6,"t":"I kad ga ugledaše glavari svećenički i sluge, povikaše: “Raspni, raspni!” Kaže im Pilat: “Uzmite ga vi i raspnite jer ja ne nalazim na njemu krivice.”"},{"v":7,"t":"Odgovoriše mu Židovi: “Mi imamo Zakon i po Zakonu on mora umrijeti jer se pravio Sinom Božjim.”"},{"v":8,"t":"Kad je Pilat čuo te riječi, još se više prestraši"},{"v":9,"t":"pa ponovno uđe u dvor i kaže Isusu: “Odakle si ti?” No Isus mu ne dade odgovora."},{"v":10,"t":"Tada mu Pilat reče: “Zar meni ne odgovaraš? Ne znaš li da imam vlast da te pustim i da imam vlast da te razapnem?”"},{"v":11,"t":"Odgovori mu Isus: “Ne bi imao nada mnom nikakve vlasti da ti nije dano odozgor. Zbog toga ima veći grijeh onaj koji me predao tebi.”"},{"v":12,"t":"Od tada ga je Pilat nastojao pustiti. No Židovi vikahu: “Ako ovoga pustiš, nisi prijatelj caru. Tko se god pravi kraljem, protivi se caru.”"},{"v":13,"t":"Čuvši te riječi, Pilat izvede Isusa i posadi na sudačku stolicu na mjestu koje se zove Litostrotos - Pločnik, hebrejski Gabata -"},{"v":14,"t":"a bijaše upravo priprava za Pashu, oko šeste ure - i kaže Židovima: “Evo kralja vašega!”"},{"v":15,"t":"Oni na to povikaše: “Ukloni! Ukloni! Raspni ga!” Kaže im Pilat: “Zar kralja vašega da razapnem?” Odgovoriše glavari svećenički: “Mi nemamo kralja osim cara!”"},{"v":16,"t":"Tada im ga preda da se razapne. Uzeše dakle Isusa."},{"v":17,"t":"I noseći svoj križ, iziđe on na mjesto zvano Lubanjsko, hebrejski Golgota."},{"v":18,"t":"Ondje ga razapeše, a s njim i drugu dvojicu, s jedne i druge strane, a Isusa u sredini."},{"v":19,"t":"A napisa Pilat i natpis te ga postavi na križ. Bilo je napisano: “Isus Nazarećanin, kralj židovski.”"},{"v":20,"t":"Taj su natpis čitali mnogi Židovi jer mjesto gdje je Isus bio raspet bijaše blizu grada, a bilo je napisano hebrejski, latinski i grčki."},{"v":21,"t":"Nato glavari svećenički rekoše Pilatu: “Nemoj pisati: 'Kralj židovski', nego da je on rekao: 'Kralj sam židovski.'”"},{"v":22,"t":"Pilat odgovori: “Što napisah, napisah!”"},{"v":23,"t":"Vojnici pak, pošto razapeše Isusa, uzeše njegove haljine i razdijeliše ih na četiri dijela - svakom vojniku po dio. A uzeše i donju haljinu, koja bijaše nešivena, otkana u komadu odozgor dodolje."},{"v":24,"t":"Rekoše zato među sobom: “Ne derimo je, nego bacimo za nju kocku pa komu dopane” - da se ispuni Pismo koje veli: Razdijeliše među se haljine moje, za odjeću moju baciše kocku. I vojnici učiniše tako."},{"v":25,"t":"Uz križ su Isusov stajale majka njegova, zatim sestra njegove majke, Marija Kleofina, i Marija Magdalena."},{"v":26,"t":"Kad Isus vidje majku i kraj nje učenika kojega je ljubio, reče majci: “Ženo! Evo ti sina!” Zatim reče učeniku: “Evo ti majke!”"},{"v":27,"t":"I od toga časa uze je učenik k sebi."},{"v":28,"t":"Nakon toga, kako je Isus znao da je sve dovršeno, da bi se ispunilo Pismo, reče: “Žedan sam.”"},{"v":29,"t":"A ondje je stajala posuda puna octa. I natakoše na izopovu trsku spužvu natopljenu octom pa je primakoše njegovim ustima."},{"v":30,"t":"Čim Isus uze ocat, reče: “Dovršeno je!” I prignuvši glavu, preda duh."},{"v":31,"t":"Kako bijaše Priprava, da ne bi tijela ostala na križu subotom, jer velik je dan bio one subote, Židovi zamoliše Pilata da se raspetima prebiju golijeni i da se skinu."},{"v":32,"t":"Dođoše dakle vojnici i prebiše golijeni prvomu i drugomu koji su s Isusom bili raspeti."},{"v":33,"t":"Kada dođoše do Isusa i vidješe da je već umro, ne prebiše mu golijeni,"},{"v":34,"t":"nego mu jedan od vojnika kopljem probode bok i odmah poteče krv i voda."},{"v":35,"t":"Onaj koji je vidio svjedoči i istinito je svjedočanstvo njegovo. On zna da govori istinu da i vi vjerujete"},{"v":36,"t":"jer se to dogodilo da se ispuni Pismo: Nijedna mu se kost neće slomiti."},{"v":37,"t":"I drugo opet Pismo veli: Gledat će onoga koga su proboli."},{"v":38,"t":"Nakon toga Josip iz Arimateje, koji je - kriomice, u strahu od Židova - bio učenik Isusov, zamoli Pilata da smije skinuti tijelo Isusovo. I dopusti mu Pilat. Josip dakle ode i skine Isusovo tijelo."},{"v":39,"t":"A dođe i Nikodem - koji je ono prije bio došao Isusu noću - i donese sa sobom oko sto libara smjese smirne i aloja."},{"v":40,"t":"Uzmu dakle tijelo Isusovo i poviju ga u povoje s miomirisima, kako je u Židova običaj za ukop."},{"v":41,"t":"A na mjestu gdje je Isus bio raspet bijaše vrt i u vrtu nov grob u koji još nitko ne bijaše položen."},{"v":42,"t":"Ondje dakle zbog židovske Priprave, jer grob bijaše blizu, polože Isusa."}]},"20":{"fa":[{"v":1,"t":"بامدادان در اول هفته، وقتی که هنوز تاریک بود، مریم مجدلیه به‌سر قبر‌آمدو دید که سنگ از قبر برداشته شده است."},{"v":2,"t":"پس دوان دوان نزد شمعون پطرس و آن شاگرد دیگرکه عیسی او را دوست می‌داشت آمده، به ایشان گفت: «خداوند را از قبر برده‌اند و نمی دانیم او راکجا گذارده‌اند.»"},{"v":3,"t":"آنگاه پطرس و آن شاگرد دیگربیرون شده، به‌جانب قبر رفتند."},{"v":4,"t":"و هر دو با هم می‌دویدند، اما آن شاگرد دیگر از پطرس پیش افتاده، اول به قبر رسید،"},{"v":5,"t":"و خم شده، کفن راگذاشته دید، لیکن داخل نشد."},{"v":6,"t":"بعد شمعون پطرس نیز از عقب او آمد و داخل قبرگشته، کفن را گذاشته دید،"},{"v":7,"t":"و دستمالی را که بر سر او بود، نه با کفن نهاده، بلکه در جای علیحده پیچیده."},{"v":8,"t":"پس آن شاگرد دیگر که اول به‌سر قبر‌آمده بود نیزداخل شده، دید و ایمان آورد."},{"v":9,"t":"زیرا هنوز کتاب را نفهمیده بودند که باید او از مردگان برخیزد."},{"v":10,"t":"پس آن دو شاگرد به مکان خود برگشتند."},{"v":11,"t":"اما مریم بیرون قبر، گریان ایستاده بود وچون می‌گریست به سوی قبر خم شده،"},{"v":12,"t":"دوفرشته را که لباس سفید در بر داشتند، یکی به طرف سر و دیگری به‌جانب قدم، در جایی که بدن عیسی گذارده بود، نشسته دید."},{"v":13,"t":"ایشان بدوگفتند: «ای زن برای چه گریانی؟» بدیشان گفت: «خداوند مرا برده‌اند و نمی دانم او را کجاگذارده‌اند.»"},{"v":14,"t":"چون این را گفت، به عقب ملتفت شده، عیسی را ایستاده دید لیکن نشناخت که عیسی است."},{"v":15,"t":"عیسی بدو گفت: «ای زن برای چه گریانی؟ که را می‌طلبی؟» چون او گمان کردکه باغبان است، بدو گفت: «ای آقا اگر تو او رابرداشته‌ای، به من بگو او را کجا گذارده‌ای تا من اورا بردارم.»"},{"v":16,"t":"عیسی بدو گفت: «ای مریم!» اوبرگشته، گفت: «ربونی (یعنی‌ای معلم ).»"},{"v":17,"t":"عیسی بدو گفت: «مرا لمس مکن زیرا که هنوزنزد پدر خود بالا نرفته‌ام. و لیکن نزد برادران من رفته، به ایشان بگو که نزد پدر خود و پدر شما وخدای خود و خدای شما می‌روم.»"},{"v":18,"t":"مریم مجدلیه آمده، شاگردان را خبر داد که «خداوند رادیدم و به من چنین گفت.»"},{"v":19,"t":"و در شام همان روز که یکشنبه بود، هنگامی که درها بسته بود، جایی که شاگردان به‌سبب ترس یهود جمع بودند، ناگاه عیسی آمده، در میان ایستاد و بدیشان گفت: «سلام بر شما باد!»"},{"v":20,"t":"و چون این را گفت، دستها و پهلوی خود را به ایشان نشان داد و شاگردان چون خداوند رادیدند، شاد گشتند."},{"v":21,"t":"باز عیسی به ایشان گفت: «سلام بر شما باد. چنانکه پدر مرا فرستاد، من نیزشما را می‌فرستم.»"},{"v":22,"t":"و چون این را گفت، دمید وبه ایشان گفت: «روح‌القدس را بیابید."},{"v":23,"t":"گناهان آنانی را که آمرزیدید، برای ایشان آمرزیده شد وآنانی را که بستید، بسته شد.»"},{"v":24,"t":"اما توما که یکی از آن دوازده بود و او را توام می‌گفتند، وقتی که عیسی آمد با ایشان نبود."},{"v":25,"t":"پس شاگردان دیگر بدو گفتند: «خداوند رادیده‌ایم.» بدیشان گفت: «تا در دو دستش جای میخها را نبینم و انگشت خود را در جای میخهانگذارم و دست خود را بر پهلویش ننهم، ایمان نخواهم آورد.»"},{"v":26,"t":"و بعد از هشت روز باز شاگردان با توما درخانه‌ای جمع بودند و درها بسته بود که ناگاه عیسی آمد و در میان ایستاده، گفت: «سلام بر شماباد.»"},{"v":27,"t":"پس به توما گفت: «انگشت خود را به اینجا بیاور و دستهای مرا ببین و دست خود رابیاور و بر پهلوی من بگذار و بی‌ایمان مباش بلکه ایمان دار.»"},{"v":28,"t":"توما در جواب وی گفت: «ای خداوند من و‌ای خدای من.»"},{"v":29,"t":"عیسی گفت: «ای توما، بعد از دیدنم ایمان آوردی؟ خوشابحال آنانی که ندیده ایمان آورند.»"},{"v":30,"t":"و عیسی معجزات دیگر بسیار نزد شاگردان نمود که در این کتاب نوشته نشد."},{"v":31,"t":"لیکن این قدرنوشته شد تا ایمان آورید که عیسی، مسیح و پسرخدا است و تا ایمان آورده به اسم او حیات یابید."}],"en":[{"v":1,"t":"Now on the first day of the week, Mary Magdalene went early, while it was still dark, to the tomb, and saw that the stone had been taken away from the tomb."},{"v":2,"t":"Therefore she ran and came to Simon Peter and to the other disciple whom Jesus loved, and said to them, “They have taken away the Lord out of the tomb, and we don’t know where they have laid him!”"},{"v":3,"t":"Therefore Peter and the other disciple went out, and they went toward the tomb."},{"v":4,"t":"They both ran together. The other disciple outran Peter and came to the tomb first."},{"v":5,"t":"Stooping and looking in, he saw the linen cloths lying there; yet he didn’t enter in."},{"v":6,"t":"Then Simon Peter came, following him, and entered into the tomb. He saw the linen cloths lying,"},{"v":7,"t":"and the cloth that had been on his head, not lying with the linen cloths, but rolled up in a place by itself."},{"v":8,"t":"So then the other disciple who came first to the tomb also entered in, and he saw and believed."},{"v":9,"t":"For as yet they didn’t know the Scripture, that he must rise from the dead."},{"v":10,"t":"So the disciples went away again to their own homes."},{"v":11,"t":"But Mary was standing outside at the tomb weeping. So as she wept, she stooped and looked into the tomb,"},{"v":12,"t":"and she saw two angels in white sitting, one at the head and one at the feet, where the body of Jesus had lain."},{"v":13,"t":"They asked her, “Woman, why are you weeping?” She said to them, “Because they have taken away my Lord, and I don’t know where they have laid him.”"},{"v":14,"t":"When she had said this, she turned around and saw Jesus standing, and didn’t know that it was Jesus."},{"v":15,"t":"Jesus said to her, “Woman, why are you weeping? Who are you looking for?” She, supposing him to be the gardener, said to him, “Sir, if you have carried him away, tell me where you have laid him, and I will take him away.”"},{"v":16,"t":"Jesus said to her, “Mary.” She turned and said to him, “Rabboni!” which is to say, “Teacher!”"},{"v":17,"t":"Jesus said to her, “Don’t hold me, for I haven’t yet ascended to my Father; but go to my brothers and tell them, ‘I am ascending to my Father and your Father, to my God and your God.’”"},{"v":18,"t":"Mary Magdalene came and told the disciples that she had seen the Lord, and that he had said these things to her."},{"v":19,"t":"When therefore it was evening on that day, the first day of the week, and when the doors were locked where the disciples were assembled, for fear of the Jews, Jesus came and stood in the middle and said to them, “Peace be to you.”"},{"v":20,"t":"When he had said this, he showed them his hands and his side. The disciples therefore were glad when they saw the Lord."},{"v":21,"t":"Jesus therefore said to them again, “Peace be to you. As the Father has sent me, even so I send you.”"},{"v":22,"t":"When he had said this, he breathed on them, and said to them, “Receive the Holy Spirit!"},{"v":23,"t":"If you forgive anyone’s sins, they have been forgiven them. If you retain anyone’s sins, they have been retained.”"},{"v":24,"t":"But Thomas, one of the twelve, called Didymus, wasn’t with them when Jesus came."},{"v":25,"t":"The other disciples therefore said to him, “We have seen the Lord!” But he said to them, “Unless I see in his hands the print of the nails, put my finger into the print of the nails, and put my hand into his side, I will not believe.”"},{"v":26,"t":"After eight days, again his disciples were inside and Thomas was with them. Jesus came, the doors being locked, and stood in the middle, and said, “Peace be to you.”"},{"v":27,"t":"Then he said to Thomas, “Reach here your finger, and see my hands. Reach here your hand, and put it into my side. Don’t be unbelieving, but believing.”"},{"v":28,"t":"Thomas answered him, “My Lord and my God!”"},{"v":29,"t":"Jesus said to him, “Because you have seen me, you have believed. Blessed are those who have not seen and have believed.”"},{"v":30,"t":"Therefore Jesus did many other signs in the presence of his disciples, which are not written in this book;"},{"v":31,"t":"but these are written that you may believe that Jesus is the Christ, the Son of God, and that believing you may have life in his name."}],"hr":[{"v":1,"t":"Prvog dana u tjednu rano ujutro, još za mraka, dođe Marija Magdalena na grob i opazi da je kamen s groba dignut."},{"v":2,"t":"Otrči stoga i dođe k Šimunu Petru i drugom učeniku, kojega je Isus ljubio, pa im reče: “Uzeše Gospodina iz groba i ne znamo gdje ga staviše.”"},{"v":3,"t":"Uputiše se onda Petar i onaj drugi učenik i dođoše na grob."},{"v":4,"t":"Trčahu obojica zajedno, ali onaj drugi učenik prestignu Petra i stiže prvi na grob."},{"v":5,"t":"Sagne se i opazi povoje gdje leže, ali ne uđe."},{"v":6,"t":"Uto dođe i Šimun Petar koji je išao za njim i uđe u grob. Ugleda povoje gdje leže"},{"v":7,"t":"i ubrus koji bijaše na glavi Isusovoj, ali nije bio uz povoje, nego napose svijen na jednome mjestu."},{"v":8,"t":"Tada uđe i onaj drugi učenik koji prvi stiže na grob i vidje i povjerova."},{"v":9,"t":"Jer oni još ne upoznaše Pisma da Isus treba da ustane od mrtvih."},{"v":10,"t":"Potom se učenici vratiše kući."},{"v":11,"t":"A Marija je stajala vani kod groba i plakala."},{"v":12,"t":"Zaplakana zaviri u grob i ugleda dva anđela u bjelini kako sjede na mjestu gdje je ležalo tijelo Isusovo - jedan kod glave, drugi kod nogu."},{"v":13,"t":"Kažu joj oni: “Ženo, što plačeš?” Odgovori im: “Uzeše Gospodina mojega i ne znam gdje ga staviše.”"},{"v":14,"t":"Rekavši to, obazre se i ugleda Isusa gdje stoji, ali nije znala da je to Isus."},{"v":15,"t":"Kaže joj Isus: “Ženo, što plačeš? Koga tražiš?” Misleći da je to vrtlar, reče mu ona: “Gospodine, ako si ga ti odnio, reci mi gdje si ga stavio i ja ću ga uzeti.”"},{"v":16,"t":"Kaže joj Isus: “Marijo!” Ona se okrene te će mu hebrejski: “Rabbuni!” - što znači: “Učitelju!”"},{"v":17,"t":"Kaže joj Isus: “Ne zadržavaj se sa mnom jer još ne uziđoh Ocu, nego idi mojoj braći i javi im: Uzlazim Ocu svomu i Ocu vašemu, Bogu svomu i Bogu vašemu.”"},{"v":18,"t":"Ode dakle Marija Magdalena i navijesti učenicima: “Vidjela sam Gospodina i on mi je to rekao.”"},{"v":19,"t":"I uvečer toga istog dana, prvog u tjednu, dok su učenici u strahu od Židova bili zatvorili vrata, dođe Isus, stane u sredinu i reče im: “Mir vama!”"},{"v":20,"t":"To rekavši, pokaza im svoje ruke i bok. I obradovaše se učenici vidjevši Gospodina."},{"v":21,"t":"Isus im stoga ponovno reče: “Mir vama! Kao što mene posla Otac i ja šaljem vas.”"},{"v":22,"t":"To rekavši, dahne u njih i kaže im: “Primite Duha Svetoga."},{"v":23,"t":"Kojima otpustite grijehe, otpuštaju im se; kojima zadržite, zadržani su im.”"},{"v":24,"t":"Ali Toma zvani Blizanac, jedan od dvanaestorice, ne bijaše s njima kad dođe Isus."},{"v":25,"t":"Govorili su mu dakle drugi učenici: “Vidjeli smo Gospodina!” On im odvrati: “Ako ne vidim na njegovim rukama biljeg čavala i ne stavim svoj prst u mjesto čavala, ako ne stavim svoju ruku u njegov bok, neću vjerovati.”"},{"v":26,"t":"I nakon osam dana bijahu njegovi učenici opet unutra, a s njima i Toma. Vrata bijahu zatvorena, a Isus dođe, stade u sredinu i reče: “Mir vama!”"},{"v":27,"t":"Zatim će Tomi: “Prinesi prst ovamo i pogledaj mi ruke! Prinesi ruku i stavi je u moj bok i ne budi nevjeran nego vjeran.”"},{"v":28,"t":"Odgovori mu Toma: “Gospodin moj i Bog moj!”"},{"v":29,"t":"Reče mu Isus: “Budući da si me vidio, povjerovao si. Blaženi koji ne vidješe, a vjeruju!”"},{"v":30,"t":"Isus je pred svojim učenicima učinio i mnoga druga znamenja koja nisu zapisana u ovoj knjizi."},{"v":31,"t":"A ova su zapisana da vjerujete: Isus je Krist, Sin Božji, i da vjerujući imate život u imenu njegovu."}]},"21":{"fa":[{"v":1,"t":"بعد از آن عیسی باز خود را در کناره دریای طبریه، به شاگردان ظاهر ساخت و بر اینطور نمودار گشت:"},{"v":2,"t":"شمعون پطرس وتومای معروف به توام و نتنائیل که از قانای جلیل بود و دو پسر زبدی و دو نفر دیگر از شاگردان اوجمع بودند."},{"v":3,"t":"شمعون پطرس به ایشان گفت: «می‌روم تا صید ماهی کنم.» به او گفتند: «مانیز باتو می‌آییم.» پس بیرون آمده، به کشتی سوارشدند و در آن شب چیزی نگرفتند."},{"v":4,"t":"و چون صبح شد، عیسی بر ساحل ایستاده بود لیکن شاگردان ندانستند که عیسی است."},{"v":5,"t":"عیسی بدیشان گفت: «ای بچه‌ها نزد شماخوراکی هست؟» به او جواب دادند که «نی.»"},{"v":6,"t":"بدیشان گفت: «دام را به طرف راست کشتی بیندازید که خواهید یافت.» پس انداختند و ازکثرت ماهی نتوانستند آن را بکشند."},{"v":7,"t":"پس آن شاگردی که عیسی او را محبت می‌نمود به پطرس گفت: «خداوند است.» چون شمعون پطرس شنید که خداوند است، جامه خود را به خویشتن پیچید چونکه برهنه بود و خود را در دریاانداخت."},{"v":8,"t":"اما شاگردان دیگر در زورق آمدند زیرااز خشکی دور نبودند، مگر قریب به دویست ذراع و دام ماهی را می‌کشیدند."},{"v":9,"t":"پس چون به خشکی آمدند، آتشی افروخته و ماهی بر آن گذارده و نان دیدند."},{"v":10,"t":"عیسی بدیشان گفت: «از ماهی‌ای که الان گرفته‌اید، بیاورید.»"},{"v":11,"t":"پس شمعون پطرس رفت و دام را برزمین کشید، پر از صد و پنجاه و سه ماهی بزرگ وبا وجودی که اینقدر بود، دام پاره نشد."},{"v":12,"t":"عیسی بدیشان گفت: «بیایید بخورید.» ولی احدی ازشاگردان جرات نکرد که از او بپرسد «تو کیستی»، زیرا می‌دانستند که خداوند است."},{"v":13,"t":"آنگاه عیسی آمد و نان را گرفته، بدیشان داد و همچنین ماهی را."},{"v":14,"t":"و این مرتبه سوم بود که عیسی بعد ازبرخاستن از مردگان، خود را به شاگردان ظاهرکرد."},{"v":15,"t":"و بعد از غذا خوردن، عیسی به شمعون پطرس گفت: «ای شمعون، پسر یونا، آیا مرابیشتر از اینها محبت می‌نمایی؟» بدو گفت: «بلی خداوندا، تو می‌دانی که تو را دوست می‌دارم.» بدو گفت: «بره های مرا خوراک بده.»"},{"v":16,"t":"باز درثانی به او گفت: «ای شمعون، پسر یونا، آیا مرامحبت می‌نمایی؟» به او گفت: «بلی خداوندا، تومی دانی که تو را دوست می‌دارم.» بدو گفت: «گوسفندان مرا شبانی کن.»"},{"v":17,"t":"مرتبه سوم بدوگفت: «ای شمعون، پسر یونا، مرا دوست می‌داری؟» پطرس محزون گشت، زیرا مرتبه سوم بدو گفت «مرا دوست می‌داری؟» پس به اوگفت: «خداوندا، تو بر همه‌چیز واقف هستی. تومی دانی که تو را دوست می‌دارم.» عیسی بدوگفت: «گوسفندان مرا خوراک ده."},{"v":18,"t":"آمین آمین به تو می‌گویم وقتی که جوان بودی، کمر خود رامی بستی و هر جا می‌خواستی می‌رفتی ولکن زمانی که پیر شوی دستهای خود را دراز خواهی کرد و دیگران تو را بسته به‌جایی که نمی خواهی تو را خواهند برد.»"},{"v":19,"t":"و بدین سخن اشاره کردکه به چه قسم موت خدا را جلال خواهد داد وچون این را گفت، به او فرمود: «از عقب من بیا.»"},{"v":20,"t":"پطرس ملتفت شده، آن شاگردی که عیسی او را محبت می‌نمود دید که از عقب می‌آید؛ وهمان بود که بر سینه وی، وقت عشا تکیه می‌زد وگفت: «خداوندا کیست آن که تو را تسلیم می‌کند.»"},{"v":21,"t":"پس چون پطرس او را دید، به عیسی گفت: «ای خداوند و او چه شود؟»"},{"v":22,"t":"عیسی بدوگفت: «اگر بخواهم که او بماند تا باز آیم تو را چه؟ تو از عقب من بیا.»"},{"v":23,"t":"پس این سخن در میان برادران شهرت یافت که آن شاگرد نخواهد مرد. لیکن عیسی بدو نگفت که نمی میرد، بلکه «اگربخواهم که او بماند تا باز آیم تو را چه.»"},{"v":24,"t":"و این شاگردی است که به این چیزها شهادت داد و اینهارا نوشت و می‌دانیم که شهادت او راست است."},{"v":25,"t":"و دیگر کارهای بسیار عیسی به‌جا آورد که اگرفرد فرد نوشته شود گمان ندارم که جهان هم گنجایش نوشته‌ها را داشته باشد."}],"en":[{"v":1,"t":"After these things, Jesus revealed himself again to the disciples at the sea of Tiberias. He revealed himself this way."},{"v":2,"t":"Simon Peter, Thomas called Didymus, Nathanael of Cana in Galilee, and the sons of Zebedee, and two others of his disciples were together."},{"v":3,"t":"Simon Peter said to them, “I’m going fishing.” They told him, “We are also coming with you.” They immediately went out and entered into the boat. That night, they caught nothing."},{"v":4,"t":"But when day had already come, Jesus stood on the beach; yet the disciples didn’t know that it was Jesus."},{"v":5,"t":"Jesus therefore said to them, “Children, have you anything to eat?” They answered him, “No.”"},{"v":6,"t":"He said to them, “Cast the net on the right side of the boat, and you will find some.” They cast it therefore, and now they weren’t able to draw it in for the multitude of fish."},{"v":7,"t":"That disciple therefore whom Jesus loved said to Peter, “It’s the Lord!” So when Simon Peter heard that it was the Lord, he wrapped his coat around himself (for he was naked), and threw himself into the sea."},{"v":8,"t":"But the other disciples came in the little boat (for they were not far from the land, but about two hundred cubits away), dragging the net full of fish."},{"v":9,"t":"So when they got out on the land, they saw a fire of coals there, with fish and bread laid on it."},{"v":10,"t":"Jesus said to them, “Bring some of the fish which you have just caught.”"},{"v":11,"t":"Simon Peter went up, and drew the net to land, full of one hundred fifty-three great fish. Even though there were so many, the net wasn’t torn."},{"v":12,"t":"Jesus said to them, “Come and eat breakfast!” None of the disciples dared inquire of him, “Who are you?” knowing that it was the Lord."},{"v":13,"t":"Then Jesus came and took the bread, gave it to them, and the fish likewise."},{"v":14,"t":"This is now the third time that Jesus was revealed to his disciples after he had risen from the dead."},{"v":15,"t":"So when they had eaten their breakfast, Jesus said to Simon Peter, “Simon, son of Jonah, do you love me more than these?” He said to him, “Yes, Lord; you know that I have affection for you.” He said to him, “Feed my lambs.”"},{"v":16,"t":"He said to him again a second time, “Simon, son of Jonah, do you love me?” He said to him, “Yes, Lord; you know that I have affection for you.” He said to him, “Tend my sheep.”"},{"v":17,"t":"He said to him the third time, “Simon, son of Jonah, do you have affection for me?” Peter was grieved because he asked him the third time, “Do you have affection for me?” He said to him, “Lord, you know everything. You know that I have affection for you.” Jesus said to him, “Feed my sheep."},{"v":18,"t":"Most certainly I tell you, when you were young, you dressed yourself and walked where you wanted to. But when you are old, you will stretch out your hands, and another will dress you and carry you where you don’t want to go.”"},{"v":19,"t":"Now he said this, signifying by what kind of death he would glorify God. When he had said this, he said to him, “Follow me.”"},{"v":20,"t":"Then Peter, turning around, saw a disciple following. This was the disciple whom Jesus loved, the one who had also leaned on Jesus’ chest at the supper and asked, “Lord, who is going to betray you?”"},{"v":21,"t":"Peter, seeing him, said to Jesus, “Lord, what about this man?”"},{"v":22,"t":"Jesus said to him, “If I desire that he stay until I come, what is that to you? You follow me.”"},{"v":23,"t":"This saying therefore went out among the brothers that this disciple wouldn’t die. Yet Jesus didn’t say to him that he wouldn’t die, but, “If I desire that he stay until I come, what is that to you?”"},{"v":24,"t":"This is the disciple who testifies about these things, and wrote these things. We know that his witness is true."},{"v":25,"t":"There are also many other things which Jesus did, which if they would all be written, I suppose that even the world itself wouldn’t have room for the books that would be written."}],"hr":[{"v":1,"t":"Poslije toga očitova se Isus ponovno učenicima na Tiberijadskome moru. Očitova se ovako:"},{"v":2,"t":"Bijahu zajedno Šimun Petar, Toma zvani Blizanac, Natanael iz Kane Galilejske, zatim Zebedejevi i još druga dva njegova učenika."},{"v":3,"t":"Kaže im Šimun Petar: “Idem ribariti.” Rekoše: “Idemo i mi s tobom.” Izađoše i uđoše u lađu, ali te noći ne uloviše ništa."},{"v":4,"t":"Kad je već svanulo, stade Isus na kraju, ali učenici nisu znali da je to Isus."},{"v":5,"t":"Kaže im Isus: “Dječice, imate li što za prismok?” Odgovoriše mu: “Nemamo.”"},{"v":6,"t":"A on im reče: “Bacite mrežu na desnu stranu lađe i naći ćete.” Baciše oni i više je ne mogoše izvući od mnoštva ribe."},{"v":7,"t":"Tada onaj učenik kojega je Isus ljubio kaže Petru: “Gospodin je!” Kad je Šimun Petar čuo da je to Gospodin, pripaše si gornju haljinu, jer bijaše gol, te se baci u more."},{"v":8,"t":"Ostali učenici dođoše s lađicom vukući mrežu s ribom jer ne bijahu daleko od kraja, samo kojih dvjesta lakata."},{"v":9,"t":"Kad iziđu na kraj, ugledaju pripravljenu žeravicu i na njoj pristavljenu ribu i kruh."},{"v":10,"t":"Kaže im Isus: “Donesite riba što ih sada uloviste.”"},{"v":11,"t":"Nato se Šimun Petar popne i izvuče na kraj mrežu punu velikih riba, sto pedeset i tri. I premda ih je bilo toliko, mreža se ne raskinu."},{"v":12,"t":"Kaže im Isus: “Hajde, doručkujte!” I nitko se od učenika ne usudi upitati ga: “Tko si ti?” Znali su da je Gospodin."},{"v":13,"t":"Isus pristupi, uzme kruh i dade im, a tako i ribu."},{"v":14,"t":"To se već treći put očitova Isus učenicima pošto uskrsnu od mrtvih."},{"v":15,"t":"Nakon doručka upita Isus Šimuna Petra: “Šimune Ivanov, ljubiš li me više nego ovi?” Odgovori mu: “Da, Gospodine, ti znaš da te volim.”"},{"v":16,"t":"Kaže mu: “Pasi jaganjce moje!” Upita ga po drugi put: “Šimune Ivanov, ljubiš li me?” Odgovori mu: “Da, Gospodine, ti znaš da te volim!” Kaže mu: “Pasi ovce moje!”"},{"v":17,"t":"Upita ga treći put: “Šimune Ivanov, voliš li me?” Ražalosti se Petar što ga upita treći put: “Voliš li me?” pa mu odgovori: “Gospodine, ti sve znaš! Tebi je poznato da te volim.” Kaže mu Isus: “Pasi ovce moje!”"},{"v":18,"t":"“Zaista, zaista kažem ti: Dok si bio mlađi, sam si se opasivao i hodio kamo si htio; ali kad ostariš, raširit ćeš ruke i drugi će te opasivati i voditi kamo nećeš.”"},{"v":19,"t":"A to mu reče nagovješćujući kakvom će smrću proslaviti Boga. Rekavši to doda: “Idi za mnom!”"},{"v":20,"t":"Petar se okrene i opazi da ga slijedi onaj učenik kojega je Isus ljubio i koji se za večere bijaše privio Isusu uz prsa i upitao ga: “Gospodine, tko će te to izdati?”"},{"v":21,"t":"Vidjevši ga, Petar kaže Isusu: “Gospodine, a što s ovim?”"},{"v":22,"t":"Odgovori mu Isus: “Ako hoću da on ostane dok ne dođem, što je tebi do toga? Ti idi za mnom!”"},{"v":23,"t":"Stoga se pronese među braćom glas da onaj učenik neće umrijeti. No Isus mu nije rekao: “Neće umrijeti”, nego: “Ako hoću da on ostane dok ne dođem, što je tebi do toga?”"},{"v":24,"t":"Taj učenik za ovo svjedoči i ovo napisa. I znamo da je istinito svjedočanstvo njegovo."},{"v":25,"t":"A ima još mnogo toga što učini Isus i kad bi se sve redom popisalo, sav svijet, mislim, ne bi obuhvatio knjiga koje bi se napisale."}]}},"ACT":{"1":{"fa":[{"v":1,"t":"صحیفه اول را انشا نمودم، ای تیوفلس، درباره همه اموری که عیسی به عمل نمودن و تعلیم دادن آنها شروع کرد."},{"v":2,"t":"تا آن روزی که رسولان برگزیده خود را به روح‌القدس حکم کرده، بالا برده شد."},{"v":3,"t":"که بدیشان نیز بعد از زحمت کشیدن خود، خویشتن را زنده ظاهر کرد به دلیلهای بسیار که در مدت چهل روز بر ایشان ظاهر می‌شد و درباره امور ملکوت خدا سخن می‌گفت."},{"v":4,"t":"و چون با ایشان جمع شد، ایشان راقدغن فرمود که «از اورشلیم جدا مشوید، بلکه منتظر آن وعده پدر باشید که از من شنیده‌اید."},{"v":5,"t":"زیرا که یحیی به آب تعمید می‌داد، لیکن شمابعد از اندک ایامی، به روح‌القدس تعمید خواهیدیافت.»"},{"v":6,"t":"پس آنانی که جمع بودند، از او سوال نموده، گفتند: «خداوندا آیا در این وقت ملکوت را براسرائیل باز برقرار خواهی داشت؟»"},{"v":7,"t":"بدیشان گفت: «از شما نیست که زمانها و اوقاتی را که پدردر قدرت خود نگاه داشته است بدانید."},{"v":8,"t":"لیکن چون روح‌القدس بر شما می‌آید، قوت خواهیدیافت و شاهدان من خواهید بود، در اورشلیم وتمامی یهودیه و سامره و تا اقصای جهان.»"},{"v":9,"t":"و چون این را گفت، وقتی که ایشان همی نگریستند، بالا برده شد و ابری او را از چشمان ایشان در ربود."},{"v":10,"t":"و چون به سوی آسمان چشم دوخته می‌بودند، هنگامی که او می‌رفت، ناگاه دومرد سفیدپوش نزد ایشان ایستاده،"},{"v":11,"t":"گفتند: «ای مردان جلیلی چرا ایستاده، به سوی آسمان نگرانید؟ همین عیسی که از نزد شما به آسمان بالابرده شد، باز خواهد آمد به همین طوری که او رابه سوی آسمان روانه دیدید.»"},{"v":12,"t":"آنگاه به اورشلیم مراجعت کردند، از کوه مسمی به زیتون که نزدیک به اورشلیم به مسافت سفر یک روز سبت است."},{"v":13,"t":"و چون داخل شدند، به بالاخانه‌ای برآمدند که در آنجا پطرس و یوحناو یعقوب و اندریاس و فیلپس و توما و برتولما ومتی و یعقوب بن حلفی و شمعون غیور و یهودای برادر بعقوب مقیم بودند."},{"v":14,"t":"و جمیع اینها با زنان و مریم مادر عیسی و برادران او به یکدل درعبادت و دعا مواظب می‌بودند."},{"v":15,"t":"و در آن ایام، پطرس در میان برادران که عدد اسامی ایشان جمله قریب به صد و بیست بود برخاسته، گفت:"},{"v":16,"t":"«ای برادران، می‌بایست آن نوشته تمام شود که روح‌القدس از زبان داودپیش گفت درباره یهودا که راهنما شد برای آنانی که عیسی را گرفتند."},{"v":17,"t":"که او با ما محسوب شده، نصیبی در این خدمت یافت."},{"v":18,"t":"پس او از اجرت ظلم خود، زمینی خریده، به روی درافتاده، ازمیان پاره شد و تمامی امعایش ریخته گشت."},{"v":19,"t":"وبر تمام سکنه اورشلیم معلوم گردید چنانکه آن زمین در لغت ایشان به حقل دما، یعنی زمین خون نامیده شد."},{"v":20,"t":"زیرا در کتاب زبور مکتوب است که خانه او خراب بشود و هیچ‌کس در آن مسکن نگیرد و نظارتش را دیگری ضبط نماید."},{"v":21,"t":"الحال می‌باید از آن مردمانی که همراهان ما بودند، درتمام آن مدتی که عیسی خداوند با ما آمد و رفت می‌کرد،"},{"v":22,"t":"از زمان تعمید یحیی، تا روزی که ازنزد ما بالا برده شد، یکی از ایشان با ما شاهدبرخاستن او بشود.»"},{"v":23,"t":"آنگاه دو نفر یعنی یوسف مسمی به برسباکه به یوستس ملقب بود و متیاس را برپا داشتند،"},{"v":24,"t":"و دعا کرده، گفتند: «تو‌ای خداوند که عارف قلوب همه هستی، بنما کدام‌یک از این دو رابرگزیده‌ای"},{"v":25,"t":"تا قسمت این خدمت و رسالت رابیابد که یهودا از آن باز افتاده، به مکان خودپیوست.»"},{"v":26,"t":"پس قرعه به نام ایشان افکندند وقرعه به نام متیاس برآمد و او با یازده رسول محسوب گشت."}],"en":[{"v":1,"t":"The first book I wrote, Theophilus, concerned all that Jesus began both to do and to teach,"},{"v":2,"t":"until the day in which he was received up, after he had given commandment through the Holy Spirit to the apostles whom he had chosen."},{"v":3,"t":"To these he also showed himself alive after he suffered, by many proofs, appearing to them over a period of forty days and speaking about God’s Kingdom."},{"v":4,"t":"Being assembled together with them, he commanded them, “Don’t depart from Jerusalem, but wait for the promise of the Father, which you heard from me."},{"v":5,"t":"For John indeed baptized in water, but you will be baptized in the Holy Spirit not many days from now.”"},{"v":6,"t":"Therefore, when they had come together, they asked him, “Lord, are you now restoring the kingdom to Israel?”"},{"v":7,"t":"He said to them, “It isn’t for you to know times or seasons which the Father has set within his own authority."},{"v":8,"t":"But you will receive power when the Holy Spirit has come upon you. You will be witnesses to me in Jerusalem, in all Judea and Samaria, and to the uttermost parts of the earth.”"},{"v":9,"t":"When he had said these things, as they were looking, he was taken up, and a cloud received him out of their sight."},{"v":10,"t":"While they were looking steadfastly into the sky as he went, behold, two men stood by them in white clothing,"},{"v":11,"t":"who also said, “You men of Galilee, why do you stand looking into the sky? This Jesus, who was received up from you into the sky, will come back in the same way as you saw him going into the sky.”"},{"v":12,"t":"Then they returned to Jerusalem from the mountain called Olivet, which is near Jerusalem, a Sabbath day’s journey away."},{"v":13,"t":"When they had come in, they went up into the upper room where they were staying, that is Peter, John, James, Andrew, Philip, Thomas, Bartholomew, Matthew, James the son of Alphaeus, Simon the Zealot, and Judas the son of James."},{"v":14,"t":"All these with one accord continued steadfastly in prayer and supplication, along with the women and Mary the mother of Jesus, and with his brothers."},{"v":15,"t":"In these days, Peter stood up in the middle of the disciples (and the number of names was about one hundred twenty), and said,"},{"v":16,"t":"“Brothers, it was necessary that this Scripture should be fulfilled, which the Holy Spirit spoke before by the mouth of David concerning Judas, who was guide to those who took Jesus."},{"v":17,"t":"For he was counted with us, and received his portion in this ministry."},{"v":18,"t":"Now this man obtained a field with the reward for his wickedness; and falling headlong, his body burst open and all his intestines gushed out."},{"v":19,"t":"It became known to everyone who lived in Jerusalem that in their language that field was called ‘Akeldama,’ that is, ‘The field of blood.’"},{"v":20,"t":"For it is written in the book of Psalms, ‘Let his habitation be made desolate. Let no one dwell in it;’ and, ‘Let another take his office.’"},{"v":21,"t":"“Of the men therefore who have accompanied us all the time that the Lord Jesus went in and out among us,"},{"v":22,"t":"beginning from the baptism of John to the day that he was received up from us, of these one must become a witness with us of his resurrection.”"},{"v":23,"t":"They put forward two: Joseph called Barsabbas, who was also called Justus, and Matthias."},{"v":24,"t":"They prayed and said, “You, Lord, who know the hearts of all men, show which one of these two you have chosen"},{"v":25,"t":"to take part in this ministry and apostleship from which Judas fell away, that he might go to his own place.”"},{"v":26,"t":"They drew lots for them, and the lot fell on Matthias; and he was counted with the eleven apostles."}],"hr":[{"v":1,"t":"Prvu sam knjigu, Teofile, sastavio o svemu što je Isus činio i učio"},{"v":2,"t":"do dana kad je uznesen pošto je dao upute apostolima koje je izabrao po Duhu Svetome."},{"v":3,"t":"Njima je poslije svoje muke mnogim dokazima pokazao da je živ, četrdeset im se dana ukazivao i govorio o kraljevstvu Božjem."},{"v":4,"t":"I dok je jednom s njima blagovao, zapovjedi im da ne napuštaju Jeruzalema, nego neka čekaju Obećanje Očevo “koje čuste od mene:"},{"v":5,"t":"Ivan je krstio vodom, a vi ćete naskoro nakon ovih dana biti kršteni Duhom Svetim.”"},{"v":6,"t":"Nato ga sabrani upitaše: “Gospodine, hoćeš li u ovo vrijeme Izraelu opet uspostaviti kraljevstvo?”"},{"v":7,"t":"On im odgovori: “Nije vaše znati vremena i zgode koje je Otac podredio svojoj vlasti."},{"v":8,"t":"Nego primit ćete snagu Duha Svetoga koji će sići na vas i bit ćete mi svjedoci u Jeruzalemu, po svoj Judeji i Samariji i sve do kraja zemlje.”"},{"v":9,"t":"Kada to reče, bi uzdignut njima naočigled i oblak ga ote njihovim očima."},{"v":10,"t":"I dok su netremice gledali kako on odlazi na nebo, gle, dva čovjeka stadoše kraj njih u bijeloj odjeći"},{"v":11,"t":"i rekoše im: “Galilejci, što stojite i gledate u nebo? Ovaj Isus koji je od vas uznesen na nebo isto će tako doći kao što ste vidjeli da odlazi na nebo.”"},{"v":12,"t":"Onda se vratiše u Jeruzalem s brda zvanoga Maslinsko, koje je blizu Jeruzalema, udaljeno jedan subotni hod."},{"v":13,"t":"I pošto uđu u grad, uspnu se u gornju sobu gdje su boravili: Petar i Ivan i Jakov i Andrija, Filip i Toma, Bartolomej i Matej, Jakov Alfejev i Šimun Revnitelj i Juda Jakovljev -"},{"v":14,"t":"svi oni bijahu jednodušno postojani u molitvi sa ženama, i Marijom, majkom Isusovom, i braćom njegovom."},{"v":15,"t":"U one dane ustade Petar među braćom - a bijaše sakupljenog naroda oko sto i dvadeset duša - i reče:"},{"v":16,"t":"“Braćo! Trebalo je da se ispuni Pismo što ga na usta Davidova proreče Duh Sveti o Judi koji bijaše vođa onih što uhvatiše Isusa."},{"v":17,"t":"A Juda se ubrajao među nas i imao udio u ovoj službi."},{"v":18,"t":"On, eto, steče predio cijenom nepravednosti pa se stropošta, raspuče po sredini i razli mu se sva utroba."},{"v":19,"t":"I svim je Jeruzalemcima znano da se onaj predio njihovim jezikom zove Akeldama, to jest Predio smrti."},{"v":20,"t":"Pisano je doista u Knjizi psalama: Njegova kuća nek opusti, nek ne bude stanovnika u njoj! Njegovo nadgledništvo nek dobije drugi!"},{"v":21,"t":"Jedan dakle od ovih ljudi što bijahu s nama za sve vrijeme što je među nama živio Gospodin Isus -"},{"v":22,"t":"počevši od krštenja Ivanova pa sve do dana kad bi uzet od nas - treba da bude svjedokom njegova uskrsnuća."},{"v":23,"t":"I postaviše dvojicu: Josipa koji se zvao Barsaba a prozvao se Just, i Matiju."},{"v":24,"t":"Onda se pomoliše: “Ti, Gospodine, poznavaoče svih srdaca, pokaži koga si od ove dvojice izabrao"},{"v":25,"t":"da primi mjesto ove apostolske službe kojoj se iznevjeri Juda da ode na svoje mjesto.”"},{"v":26,"t":"Onda baciše kocke i kocka pade na Matiju; tako bi pribrojen jedanaestorici apostola."}]},"2":{"fa":[{"v":1,"t":"و چون روز پنطیکاست رسید، به یک دل در یکجا بودند."},{"v":2,"t":"که ناگاه آوازی چون صدای وزیدن باد شدید از آسمان آمد و تمام آن خانه را که در آنجا نشسته بودند پر ساخت."},{"v":3,"t":"وزبانه های منقسم شده، مثل زبانه های آتش بدیشان ظاهر گشته، بر هر یکی از ایشان قرار گرفت."},{"v":4,"t":"و همه از روح‌القدس پر گشته، به زبانهای مختلف، به نوعی که روح بدیشان قدرت تلفظ بخشید، به سخن‌گفتن شروع کردند."},{"v":5,"t":"و مردم یهود دین دار از هر طایفه زیر فلک دراورشلیم منزل می‌داشتند."},{"v":6,"t":"پس چون این صدابلند شد گروهی فراهم شده در حیرت افتادندزیرا هر کس لغت خود را از ایشان شنید."},{"v":7,"t":"و همه مبهوت و متعجب شده به یکدیگر می‌گفتند: «مگر همه اینها که حرف می‌زنند جلیلی نیستند؟"},{"v":8,"t":"پس چون است که هر یکی از ما لغت خود را که در آن تولد یافته‌ایم می‌شنویم؟"},{"v":9,"t":"پارتیان و مادیان و عیلامیان و ساکنان جزیره و یهودیه و کپدکیا وپنطس و آسیا"},{"v":10,"t":"و فریجیه و پمفلیه و مصر ونواحی لبیا که متصل به قیروان است و غربا از روم یعنی یهودیان و جدیدان"},{"v":11,"t":"و اهل کریت و عرب اینها را می‌شنویم که به زبانهای ما ذکر کبریایی خدا می‌کنند.»"},{"v":12,"t":"پس همه در حیرت و شک افتاده، به یکدیگر گفتند: «این به کجا خواهدانجامید؟»"},{"v":13,"t":"اما بعضی استهزاکنان گفتند که «ازخمر تازه مست شده‌اند!»"},{"v":14,"t":"پس پطرس با آن یازده برخاسته، آواز خودرا بلند کرده، بدیشان گفت: «ای مردان یهود وجمیع سکنه اورشلیم، این را بدانید و سخنان مرافرا‌گیرید."},{"v":15,"t":"زیرا که اینها مست نیستند چنانکه شما گمان می‌برید، زیرا که ساعت سوم از روزاست."},{"v":16,"t":"بلکه این همان است که یوئیل نبی گفت"},{"v":17,"t":"که “خدا می‌گوید در ایام آخر چنین خواهدبود که از روح خود بر تمام بشر خواهم ریخت وپسران و دختران شما نبوت کنند و جوانان شما رویاها و پیران شما خوابها خواهند دید؛"},{"v":18,"t":"و برغلامان و کنیزان خود در آن ایام از روح خودخواهم ریخت و ایشان نبوت خواهند نمود."},{"v":19,"t":"واز بالا در افلاک، عجایب و از پایین در زمین، آیات را از خون و آتش و بخار دود به ظهور آورم."},{"v":20,"t":"خورشید به ظلمت و ماه به خون مبدل گرددقبل از وقوع روز عظیم مشهور خداوند."},{"v":21,"t":"وچنین خواهد بود که هر‌که نام خداوند را بخواند، نجات یابد.”"},{"v":22,"t":"«ای مردان اسرائیلی این سخنان را بشنوید. عیسی ناصری مردی که نزد شما از جانب خدامبرهن گشت به قوات و عجایب و آیاتی که خدادر میان شما از او صادر گردانید، چنانکه خودمی دانید،"},{"v":23,"t":"این شخص چون برحسب اراده مستحکم و پیشدانی خدا تسلیم شد، شما به‌دست گناهکاران بر صلیب کشیده، کشتید،"},{"v":24,"t":"که خدا دردهای موت را گسسته، او را برخیزانیدزیرا محال بود که موت او را در بند نگاه دارد،"},{"v":25,"t":"زیرا که داود درباره وی می‌گوید: “خداوند راهمواره پیش روی خود دیده‌ام که به‌دست راست من است تا جنبش نخورم؛"},{"v":26,"t":"از این سبب دلم شادگردید و زبانم به وجد آمد بلکه جسدم نیز در امیدساکن خواهد بود؛"},{"v":27,"t":"زیرا که نفس مرا در عالم اموات نخواهی گذاشت و اجازت نخواهی داد که قدوس تو فساد را ببیند."},{"v":28,"t":"طریقهای حیات را به من آموختی و مرا از روی خود به خرمی سیرگردانیدی.”"},{"v":29,"t":"«ای برادران، می‌توانم درباره داود پطریارخ با شما بی‌محابا سخن گویم که او وفات نموده، دفن شد و مقبره او تا امروز در میان ماست."},{"v":30,"t":"پس چون نبی بود و دانست که خدا برای او قسم خوردکه از ذریت صلب او بحسب جسد، مسیح رابرانگیزاند تا بر تخت او بنشیند،"},{"v":31,"t":"درباره قیامت مسیح پیش دیده، گفت که نفس او در عالم اموات گذاشته نشود و جسد او فساد را نبیند."},{"v":32,"t":"پس همان عیسی را خدا برخیزانید و همه ما شاهد برآن هستیم."},{"v":33,"t":"پس چون به‌دست راست خدا بالابرده شد، روح‌القدس موعود را از پدر یافته، این را که شما حال می‌بینید و می‌شنوید ریخته است."},{"v":34,"t":"زیرا که داود به آسمان صعود نکرد لیکن خودمی گوید “خداوند به خداوند من گفت بر دست راست من بنشین"},{"v":35,"t":"تا دشمنانت را پای انداز توسازم.”"},{"v":36,"t":"پس جمیع خاندان اسرائیل یقین بدانندکه خدا همین عیسی را که شما مصلوب کردیدخداوند و مسیح ساخته است.»"},{"v":37,"t":"چون شنیدند دلریش گشته، به پطرس وسایر رسولان گفتند: «ای برادران چه کنیم؟»"},{"v":38,"t":"پطرس بدیشان گفت: «توبه کنید و هر یک ازشما به اسم عیسی مسیح بجهت آمرزش گناهان تعمید گیرید و عطای روح‌القدس را خواهیدیافت."},{"v":39,"t":"زیرا که این وعده است برای شما وفرزندان شما و همه آنانی که دورند یعنی هرکه خداوند خدای ما او را بخواند.»"},{"v":40,"t":"و به سخنان بسیار دیگر، بدیشان شهادت داد و موعظه نموده، گفت که «خود را از این فرقه کجرو رستگارسازید.»"},{"v":41,"t":"پس ایشان کلام او را پذیرفته، تعمیدگرفتند و در همان روز تخمین سه هزار نفر بدیشان پیوستند"},{"v":42,"t":"و در تعلیم رسولان ومشارکت ایشان و شکستن نان و دعاها مواظبت می‌نمودند."},{"v":43,"t":"و همه خلق ترسیدند و معجزات وعلامات بسیار از دست رسولان صادر می‌گشت."},{"v":44,"t":"و همه ایمانداران با هم می‌زیستند و درهمه‌چیز شریک می‌بودند"},{"v":45,"t":"و املاک و اموال خود را فروخته، آنها را به هر کس به قدراحتیاجش تقسیم می‌کردند."},{"v":46,"t":"و هر روزه درهیکل به یکدل پیوسته می‌بودند و در خانه‌ها نان را پاره می‌کردند و خوراک را به خوشی وساده دلی می‌خوردند."},{"v":47,"t":"و خدا را حمد می‌گفتندو نزد تمامی خلق عزیز می‌گردیدند و خداوند هرروزه ناجیان را بر کلیسا می‌افزود."}],"en":[{"v":1,"t":"Now when the day of Pentecost had come, they were all with one accord in one place."},{"v":2,"t":"Suddenly there came from the sky a sound like the rushing of a mighty wind, and it filled all the house where they were sitting."},{"v":3,"t":"Tongues like fire appeared and were distributed to them, and one sat on each of them."},{"v":4,"t":"They were all filled with the Holy Spirit and began to speak with other languages, as the Spirit gave them the ability to speak."},{"v":5,"t":"Now there were dwelling in Jerusalem Jews, devout men, from every nation under the sky."},{"v":6,"t":"When this sound was heard, the multitude came together and were bewildered, because everyone heard them speaking in his own language."},{"v":7,"t":"They were all amazed and marveled, saying to one another, “Behold, aren’t all these who speak Galileans?"},{"v":8,"t":"How do we hear, everyone in our own native language?"},{"v":9,"t":"Parthians, Medes, Elamites, and people from Mesopotamia, Judea, Cappadocia, Pontus, Asia,"},{"v":10,"t":"Phrygia, Pamphylia, Egypt, the parts of Libya around Cyrene, visitors from Rome, both Jews and proselytes,"},{"v":11,"t":"Cretans and Arabians—we hear them speaking in our languages the mighty works of God!”"},{"v":12,"t":"They were all amazed and were perplexed, saying to one another, “What does this mean?”"},{"v":13,"t":"Others, mocking, said, “They are filled with new wine.”"},{"v":14,"t":"But Peter, standing up with the eleven, lifted up his voice and spoke out to them, “You men of Judea and all you who dwell at Jerusalem, let this be known to you, and listen to my words."},{"v":15,"t":"For these aren’t drunken, as you suppose, seeing it is only the third hour of the day."},{"v":16,"t":"But this is what has been spoken through the prophet Joel:"},{"v":17,"t":"‘It will be in the last days, says God, that I will pour out my Spirit on all flesh. Your sons and your daughters will prophesy. Your young men will see visions. Your old men will dream dreams."},{"v":18,"t":"Yes, and on my servants and on my handmaidens in those days, I will pour out my Spirit, and they will prophesy."},{"v":19,"t":"I will show wonders in the sky above, and signs on the earth beneath: blood, and fire, and billows of smoke."},{"v":20,"t":"The sun will be turned into darkness, and the moon into blood, before the great and glorious day of the Lord comes."},{"v":21,"t":"It will be that whoever will call on the name of the Lord will be saved.’"},{"v":22,"t":"“Men of Israel, hear these words! Jesus of Nazareth, a man approved by God to you by mighty works and wonders and signs which God did by him among you, even as you yourselves know,"},{"v":23,"t":"him, being delivered up by the determined counsel and foreknowledge of God, you have taken by the hand of lawless men, crucified and killed;"},{"v":24,"t":"whom God raised up, having freed him from the agony of death, because it was not possible that he should be held by it."},{"v":25,"t":"For David says concerning him, ‘I saw the Lord always before my face, for he is on my right hand, that I should not be moved."},{"v":26,"t":"Therefore my heart was glad, and my tongue rejoiced. Moreover my flesh also will dwell in hope,"},{"v":27,"t":"because you will not leave my soul in Hades, neither will you allow your Holy One to see decay."},{"v":28,"t":"You made known to me the ways of life. You will make me full of gladness with your presence.’"},{"v":29,"t":"“Brothers, I may tell you freely of the patriarch David, that he both died and was buried, and his tomb is with us to this day."},{"v":30,"t":"Therefore, being a prophet, and knowing that God had sworn with an oath to him that of the fruit of his body, according to the flesh, he would raise up the Christ to sit on his throne,"},{"v":31,"t":"he foreseeing this, spoke about the resurrection of the Christ, that his soul wasn’t left in Hades, and his flesh didn’t see decay."},{"v":32,"t":"This Jesus God raised up, to which we all are witnesses."},{"v":33,"t":"Being therefore exalted by the right hand of God, and having received from the Father the promise of the Holy Spirit, he has poured out this which you now see and hear."},{"v":34,"t":"For David didn’t ascend into the heavens, but he says himself, ‘The Lord said to my Lord, “Sit by my right hand"},{"v":35,"t":"until I make your enemies a footstool for your feet.”’"},{"v":36,"t":"“Let all the house of Israel therefore know certainly that God has made him both Lord and Christ, this Jesus whom you crucified.”"},{"v":37,"t":"Now when they heard this, they were cut to the heart, and said to Peter and the rest of the apostles, “Brothers, what shall we do?”"},{"v":38,"t":"Peter said to them, “Repent and be baptized, every one of you, in the name of Jesus Christ for the forgiveness of sins, and you will receive the gift of the Holy Spirit."},{"v":39,"t":"For the promise is to you and to your children, and to all who are far off, even as many as the Lord our God will call to himself.”"},{"v":40,"t":"With many other words he testified and exhorted them, saying, “Save yourselves from this crooked generation!”"},{"v":41,"t":"Then those who gladly received his word were baptized. There were added that day about three thousand souls."},{"v":42,"t":"They continued steadfastly in the apostles’ teaching and fellowship, in the breaking of bread, and prayer."},{"v":43,"t":"Fear came on every soul, and many wonders and signs were done through the apostles."},{"v":44,"t":"All who believed were together, and had all things in common."},{"v":45,"t":"They sold their possessions and goods, and distributed them to all, according as anyone had need."},{"v":46,"t":"Day by day, continuing steadfastly with one accord in the temple, and breaking bread at home, they took their food with gladness and singleness of heart,"},{"v":47,"t":"praising God and having favor with all the people. The Lord added to the assembly day by day those who were being saved."}],"hr":[{"v":1,"t":"Kad je napokon došao dan Pedesetnice, svi su bili zajedno na istome mjestu."},{"v":2,"t":"I eto iznenada šuma s neba, kao kad se digne silan vjetar. Ispuni svu kuću u kojoj su bili."},{"v":3,"t":"I pokažu im se kao neki ognjeni razdijeljeni jezici te siđe po jedan na svakoga od njih."},{"v":4,"t":"Svi se napuniše Duha Svetoga i počeše govoriti drugim jezicima, kako im već Duh davaše zboriti."},{"v":5,"t":"A u Jeruzalemu su boravili Židovi, ljudi pobožni iz svakog naroda pod nebom."},{"v":6,"t":"Pa kad nasta ona huka, strča se mnoštvo i smetÄe jer ih je svatko čuo govoriti svojim jezikom."},{"v":7,"t":"Svi su bili izvan sebe i divili se govoreći: “Gle! Nisu li svi ovi što govore Galilejci?"},{"v":8,"t":"Pa kako to da ih svatko od nas čuje na svojem materinskom jeziku?"},{"v":9,"t":"Parti, Međani, Elamljani, žitelji Mezopotamije, Judeje i Kapadocije, Ponta i Azije,"},{"v":10,"t":"Frigije i Pamfilije, Egipta i krajeva libijskih oko Cirene, pridošlice Rimljani,"},{"v":11,"t":"Židovi i sljedbenici, Krećani i Arapi - svi ih mi čujemo gdje našim jezicima razglašuju veličanstvena djela Božja.”"},{"v":12,"t":"Svi su izvan sebe zbunjeno jedan drugog pitali: “Što bi to moglo biti?”"},{"v":13,"t":"Drugi su pak, podrugujući se, govorili: “Slatkog su se vina ponapili!”"},{"v":14,"t":"A Petar zajedno s jedanaestoricom ustade, podiže glas i prozbori: “Židovi i svi što boravite u Jeruzalemu, ovo znajte i riječi mi poslušajte:"},{"v":15,"t":"Nisu ovi pijani, kako vi mislite - ta istom je treća ura dana -"},{"v":16,"t":"nego to je ono što je rečeno po proroku Joelu:"},{"v":17,"t":"“U posljednje dane, govori Bog: Izlit ću Duha svoga na svako tijelo i proricat će vaši sinovi i kćeri, vaši će mladići gledati viđenja, a starci vaši sne sanjati."},{"v":18,"t":"Čak ću i na sluge i sluškinje svoje izliti Duha svojeg u dane one i proricat će."},{"v":19,"t":"Pokazat ću čudesa na nebu gore i znamenja na zemlji dolje, krv i oganj i stupove dima."},{"v":20,"t":"Sunce će se prometnut u tminu, a mjesec u krv prije nego svane Dan Gospodnji velik i slavan."},{"v":21,"t":"I tko god prizove ime Gospodnje bit će spašen.”"},{"v":22,"t":"“Izraelci, čujte ove riječi: Isusa Nazarećanina, čovjeka kojega Bog pred vama potvrdi silnim djelima, čudesima i znamenjima koja, kao što znate, po njemu učini među vama -"},{"v":23,"t":"njega, predana po odlučenu naumu i promislu Božjem, po rukama bezakonika razapeste i pogubiste."},{"v":24,"t":"Ali Bog ga uskrisi oslobodivši ga grozote smrti jer ne bijaše moguće da ona njime ovlada."},{"v":25,"t":"David doista za nj kaže: Gospodin mi je svagda pred očima jer mi je zdesna da ne posrnem."},{"v":26,"t":"Stog mi se raduje srce i kliče jezik, pa i tijelo mi spokojno počiva."},{"v":27,"t":"Jer mi nećeš ostaviti dušu u Podzemlju ni dati da pravednik tvoj truleži ugleda."},{"v":28,"t":"Pokazat ćeš mi stazu života, ispuniti me radošću lica svoga."},{"v":29,"t":"Braćo, dopustite da vam otvoreno kažem: praotac je David umro, pokopan je i eno mu među nama groba sve do današnjeg dana."},{"v":30,"t":"Ali kako je bio prorok i znao da mu se zakletvom zakle Bog plod utrobe njegove posaditi na prijestolje njegovo,"},{"v":31,"t":"unaprijed je vidio i navijestio uskrsnuće Kristovo: Nije ostavljen u Podzemlju niti mu tijelo truleži ugleda."},{"v":32,"t":"Toga Isusa uskrisi Bog! Svi smo mi tomu svjedoci."},{"v":33,"t":"Desnicom dakle Božjom uzvišen, primio je od Oca Obećanje, Duha Svetoga, i izlio ga kako i sami gledate i slušate."},{"v":34,"t":"Ta David nije bio uznesen na nebesa, a veli: Reče Gospodin Gospodinu mojemu: 'Sjedi mi zdesna'"},{"v":35,"t":"dok ne položim neprijatelje tvoje za podnožje nogama tvojim!"},{"v":36,"t":"Pouzdano dakle neka znade sav dom Izraelov da je toga Isusa kojega vi razapeste Bog učinio i Gospodinom i Kristom.”"},{"v":37,"t":"Kad su to čuli, duboko potreseni rekoše Petru i drugim apostolima: “Što nam je činiti, braćo?”"},{"v":38,"t":"Petar će im: “Obratite se i svatko od vas neka se krsti u ime Isusa Krista da vam se oproste grijesi i primit ćete dar, Duha Svetoga."},{"v":39,"t":"Ta za vas je ovo obećanje i za djecu vašu i za sve one izdaleka, koje pozove Gospodin Bog naš.”"},{"v":40,"t":"I mnogim je drugim riječima još svjedočio i hrabrio ih: “Spasite se od naraštaja ovog opakog!”"},{"v":41,"t":"I oni prigrliše riječ njegovu i krstiše se te im se u onaj dan pridruži oko tri tisuće duša."},{"v":42,"t":"Bijahu postojani u nauku apostolskom, u zajedništvu, lomljenju kruha i molitvama."},{"v":43,"t":"Strahopoštovanje obuzimaše svaku dušu: apostoli su činili mnoga čudesa i znamenja."},{"v":44,"t":"Svi koji prigrliše vjeru bijahu združeni i sve im bijaše zajedničko."},{"v":45,"t":"Sva bi imanja i dobra prodali porazdijelili svima kako bi tko trebao."},{"v":46,"t":"Svaki bi dan jednodušno i postojano hrlili u Hram, u kućama bi lomili kruh te u radosti i prostodušnosti srca zajednički uzimali hranu"},{"v":47,"t":"hvaleći Boga i uživajući naklonost svega naroda. Gospodin je pak danomice zajednici pridruživao spasenike."}]},"3":{"fa":[{"v":1,"t":"و در ساعت نهم، وقت نماز، پطرس و یوحنا با هم به هیکل می‌رفتند."},{"v":2,"t":"ناگاه مردی را که لنگ مادرزاد بود می‌بردند که او را هرروزه بر آن در هیکل که جمیل نام داردمی گذاشتند تا از روندگان به هیکل صدقه بخواهد."},{"v":3,"t":"آن شخص چون پطرس و یوحنا رادید که می‌خواهند به هیکل داخل شوند، صدقه خواست."},{"v":4,"t":"اما پطرس با یوحنا بر وی نیک نگریسته، گفت: «به ما بنگر.»"},{"v":5,"t":"پس بر ایشان نظرافکنده، منتظر بود که از ایشان چیزی بگیرد."},{"v":6,"t":"آنگاه پطرس گفت: «مرا طلا و نقره نیست، اماآنچه دارم به تو می‌دهم. به نام عیسی مسیح ناصری برخیز و بخرام!»"},{"v":7,"t":"و دست راستش راگرفته او را برخیزانید که در ساعت پایها و ساقهای او قوت گرفت"},{"v":8,"t":"و برجسته بایستاد وخرامید و با ایشان خرامان و جست و خیزکنان وخدا را حمدگویان داخل هیکل شد."},{"v":9,"t":"و جمیع قوم او را خرامان و خدا راتسبیح خوانان دیدند."},{"v":10,"t":"و چون او را شناختند که همان است که به در جمیل هیکل بجهت صدقه می‌نشست، به‌سبب این امر که بر او واقع شد، متعجب و متحیر گردیدند."},{"v":11,"t":"و چون آن لنگ شفایافته به پطرس و یوحنا متمسک بود، تمامی قوم در رواقی که به سلیمانی مسمی است، حیرت زده بشتاب گرد ایشان جمع شدند."},{"v":12,"t":"آنگاه پطرس ملتفت شده، بدان جماعت خطاب کرد که «ای مردان اسرائیلی، چرا از این کار تعجب دارید و چرا بر ما چشم دوخته‌اید که گویا به قوت و تقوای خود این شخص را خرامان ساختیم؟"},{"v":13,"t":"خدای ابراهیم و اسحاق و یعقوب، خدای اجداد ما، بنده خود عیسی را جلال داد که شما تسلیم نموده، او را در حضور پیلاطس انکارکردید، هنگامی که او حکم به رهانیدنش داد."},{"v":14,"t":"اما شما آن قدوس و عادل را منکر شده، خواستید که مردی خون ریز به شما بخشیده شود."},{"v":15,"t":"و رئیس حیات را کشتید که خدا او را ازمردگان برخیزانید و ما شاهد بر او هستیم."},{"v":16,"t":"و به‌سبب ایمان به اسم او، اسم او این شخص را که می‌بینید و می‌شناسید قوت بخشیده است. بلی آن ایمانی که به وسیله اوست این کس را پیش روی همه شما این صحت کامل داده است."},{"v":17,"t":"«و الحال‌ای برادران، می‌دانم که شما وچنین حکام شما این را به‌سبب ناشناسایی کردید."},{"v":18,"t":"و لیکن خدا آن اخباری را که به زبان جمیع انبیای خود، پیش گفته بود که مسیح باید زحمت بیند، همینطور به انجام رسانید."},{"v":19,"t":"پس توبه وبازگشت کنید تا گناهان شما محو گردد و تا اوقات استراحت از حضور خداوند برسد."},{"v":20,"t":"و عیسی مسیح را که از اول برای شما اعلام شده بودبفرستد،"},{"v":21,"t":"که می‌باید آسمان او را پذیرد تا زمان معاد همه‌چیز که خدا از بدوعالم به زبان جمیع انبیای مقدس خود، از آن اخبار نمود."},{"v":22,"t":"زیراموسی به اجداد گفت که خداوند خدای شما نبی مثل من، از میان برادران شما برای شما برخواهدانگیخت. کلام او را در هر‌چه به شما تکلم کندبشنوید؛"},{"v":23,"t":"و هر نفسی که آن نبی را نشنود، از قوم منقطع گردد."},{"v":24,"t":"و جمیع انبیا نیز از سموئیل وآنانی که بعد از او تکلم کردند از این ایام اخبارنمودند."},{"v":25,"t":"شما هستید اولاد پیغمبران و آن عهدی که خدا با اجداد ما بست، وقتی که به ابراهیم گفت از ذریت تو جمیع قبایل زمین، برکت خواهند یافت"},{"v":26,"t":"برای شما اولا خدا بنده خودعیسی را برخیزانیده، فرستاد تا شما را برکت دهدبه برگردانیدن هر یکی از شما از گناهانش.»"}],"en":[{"v":1,"t":"Peter and John were going up into the temple at the hour of prayer, the ninth hour."},{"v":2,"t":"A certain man who was lame from his mother’s womb was being carried, whom they laid daily at the door of the temple which is called Beautiful, to ask gifts for the needy of those who entered into the temple."},{"v":3,"t":"Seeing Peter and John about to go into the temple, he asked to receive gifts for the needy."},{"v":4,"t":"Peter, fastening his eyes on him, with John, said, “Look at us.”"},{"v":5,"t":"He listened to them, expecting to receive something from them."},{"v":6,"t":"But Peter said, “I have no silver or gold, but what I have, that I give you. In the name of Jesus Christ of Nazareth, get up and walk!”"},{"v":7,"t":"He took him by the right hand and raised him up. Immediately his feet and his ankle bones received strength."},{"v":8,"t":"Leaping up, he stood and began to walk. He entered with them into the temple, walking, leaping, and praising God."},{"v":9,"t":"All the people saw him walking and praising God."},{"v":10,"t":"They recognized him, that it was he who used to sit begging for gifts for the needy at the Beautiful Gate of the temple. They were filled with wonder and amazement at what had happened to him."},{"v":11,"t":"As the lame man who was healed held on to Peter and John, all the people ran together to them in the porch that is called Solomon’s, greatly wondering."},{"v":12,"t":"When Peter saw it, he responded to the people, “You men of Israel, why do you marvel at this man? Why do you fasten your eyes on us, as though by our own power or godliness we had made him walk?"},{"v":13,"t":"The God of Abraham, Isaac, and Jacob, the God of our fathers, has glorified his Servant Jesus, whom you delivered up and denied in the presence of Pilate, when he had determined to release him."},{"v":14,"t":"But you denied the Holy and Righteous One and asked for a murderer to be granted to you,"},{"v":15,"t":"and killed the Prince of life, whom God raised from the dead, to which we are witnesses."},{"v":16,"t":"By faith in his name, his name has made this man strong, whom you see and know. Yes, the faith which is through him has given him this perfect soundness in the presence of you all."},{"v":17,"t":"“Now, brothers, I know that you did this in ignorance, as did also your rulers."},{"v":18,"t":"But the things which God announced by the mouth of all his prophets, that Christ should suffer, he thus fulfilled."},{"v":19,"t":"“Repent therefore, and turn again, that your sins may be blotted out, so that there may come times of refreshing from the presence of the Lord,"},{"v":20,"t":"and that he may send Christ Jesus, who was ordained for you before,"},{"v":21,"t":"whom heaven must receive until the times of restoration of all things, which God spoke long ago by the mouth of his holy prophets."},{"v":22,"t":"For Moses indeed said to the fathers, ‘The Lord God will raise up a prophet for you from among your brothers, like me. You shall listen to him in all things whatever he says to you."},{"v":23,"t":"It will be that every soul that will not listen to that prophet will be utterly destroyed from among the people.’"},{"v":24,"t":"Yes, and all the prophets from Samuel and those who followed after, as many as have spoken, also told of these days."},{"v":25,"t":"You are the children of the prophets, and of the covenant which God made with our fathers, saying to Abraham, ‘All the families of the earth will be blessed through your offspring.’"},{"v":26,"t":"God, having raised up his servant Jesus, sent him to you first to bless you, in turning away every one of you from your wickedness.”"}],"hr":[{"v":1,"t":"Petar i Ivan uzlazili su u Hram na devetu molitvenu uru."},{"v":2,"t":"Upravo su donosili nekog čovjeka, hroma od majčine utrobe; njega bi svaki dan postavljali kod hramskih vrata, zvanih Divna, da prosi milostinju od onih koji ulaze u Hram."},{"v":3,"t":"On ugleda Petra i Ivana upravo kad zakoračiše u Hram te zamoli milostinju."},{"v":4,"t":"Petar ga zajedno s Ivanom prodorno pogleda i reče: “Pogledaj u nas!”"},{"v":5,"t":"Dok ih je molećivo motrio očekujući od njih nešto dobiti,"},{"v":6,"t":"reče mu Petar: “Srebra i zlata nema u mene, ali što imam - to ti dajem: u ime Isusa Krista Nazarećanina hodaj!”"},{"v":7,"t":"I uhvativši ga za desnu ruku, pridiže ga: umah mu omoćaše noge i gležnjevi"},{"v":8,"t":"pa skoči, uspravi se, stane hodati te uđe s njima u Hram hodajući, poskakujući i hvaleći Boga."},{"v":9,"t":"Sav ga narod vidje kako hoda i hvali Boga."},{"v":10,"t":"Razabraše da je to on - onaj koji je na Divnim vratima Hrama prosio milostinju - i ostadoše zapanjeni i izvan sebe zbog onoga što se s njim dogodilo."},{"v":11,"t":"Kako se pak on držao Petra i Ivana, sav se narod zapanjen strča k njima u trijem zvani Salomonov."},{"v":12,"t":"Kada to vidje Petar, obrati se narodu: “Izraelci, što se ovomu čudite? Ili što nas gledate kao da smo svojom snagom ili pobožnošću postigli da ovaj prohoda?"},{"v":13,"t":"Bog Abrahamov, Izakov i Jakovljev, Bog otaca naših, proslavi slugu svoga, Isusa kojega vi predadoste i kojega se odrekoste pred Pilatom kad već bijaše odlučio pustiti ga."},{"v":14,"t":"Vi se odrekoste Sveca i Pravednika, a izmoliste da vam se daruje ubojica."},{"v":15,"t":"Začetnika života ubiste. Ali Bog ga uskrisi od mrtvih, čemu smo mi svjedoci.”"},{"v":16,"t":"“I po vjeri u njegovo ime, to je ime dalo snagu ovomu kojega gledate i poznate: vjera u Njega vratila je ovomu potpuno zdravlje naočigled vas sviju.”"},{"v":17,"t":"“I sada, braćo, znam da ste ono uradili iz neznanja kao i glavari vaši."},{"v":18,"t":"Ali Bog tako ispuni što unaprijed navijesti po ustima svih proroka: da će njegov Pomazanik trpjeti."},{"v":19,"t":"Pokajte se dakle i obratite da se izbrišu grijesi vaši"},{"v":20,"t":"pa od Gospodina dođu vremena rashlade te on pošalje vama unaprijed namijenjenog Pomazanika, Isusa.”"},{"v":21,"t":"Njega treba da nebo pridrži do vremena uspostave svega što obeća Bog na usta svetih proroka svojih odvijeka.”"},{"v":22,"t":"“Mojsije tako reče: Proroka poput mene od vaše braće podignut će vam Gospodin, Bog vaš. Njega slušajte u svemu što vam god reče."},{"v":23,"t":"I svaka duša koja ne posluša toga proroka, neka se iskorijeni iz naroda.”"},{"v":24,"t":"“I svi Proroci koji su - od Samuela dalje - govorili, također su navijestili ove dane.”"},{"v":25,"t":"“Vi ste sinovi proroka i Saveza koji sklopi Bog s ocima vašim govoreći Abrahamu: Potomstvom će se tvojim blagoslivljati sva plemena zemlje."},{"v":26,"t":"Vama najprije podiže Bog Slugu svoga i posla ga blagoslivljati vas da se svatko obrati od opačina svojih.”"}]},"4":{"fa":[{"v":1,"t":"و چون ایشان با قوم سخن می‌گفتند، کهنه وسردار سپاه هیکل و صدوقیان بر سر ایشان تاختند،"},{"v":2,"t":"چونکه مضطرب بودند از اینکه ایشان قوم را تعلیم می‌دادند و در عیسی به قیامت ازمردگان اعلام می‌نمودند."},{"v":3,"t":"پس دست بر ایشان انداخته، تا فردا محبوس نمودند زیرا که آن، وقت عصر بود."},{"v":4,"t":"اما بسیاری از آنانی که کلام را شنیدند ایمان آوردند و عدد ایشان قریب به پنج هزاررسید."},{"v":5,"t":"بامدادان روسا و مشایخ و کاتبان ایشان دراورشلیم فراهم آمدند،"},{"v":6,"t":"با حنای رئیس کهنه وقیافا و یوحنا و اسکندر و همه کسانی که از قبیله رئیس کهنه بودند."},{"v":7,"t":"و ایشان را در میان بداشتند واز ایشان پرسیدند که «شما به کدام قوت و به چه نام این کار را کرده‌اید؟»"},{"v":8,"t":"آنگاه پطرس ازروح‌القدس پر شده، بدیشان گفت: «ای روسای قوم و مشایخ اسرائیل،"},{"v":9,"t":"اگر امروز از ما بازپرس می‌شود درباره احسانی که بدین مرد ضعیف شده، یعنی به چه سبب او صحت یافته است،"},{"v":10,"t":"جمیع شما و تمام قوم اسرائیل را معلوم باد که به نام عیسی مسیح ناصری که شما مصلوب کردید و خدا او را از مردگان برخیزانید، در او این کس به حضور شما تندرست ایستاده است."},{"v":11,"t":"این است آن سنگی که شما معماران آن را رد کردید والحال سر زاویه شده است."},{"v":12,"t":"و در هیچ‌کس غیراز او نجات نیست زیرا که اسمی دیگر زیر آسمان به مردم عطانشده که بدان باید ما نجات یابیم.»"},{"v":13,"t":"پس چون دلیری پطرس و یوحنا را دیدندو دانستند که مردم بی‌علم و امی هستند، تعجب کردند و ایشان را شناختند که از همراهان عیسی بودند."},{"v":14,"t":"و چون آن شخص را که شفا یافته بود باایشان ایستاده دیدند، نتوانستند به ضد ایشان چیزی گویند."},{"v":15,"t":"پس حکم کردند که ایشان ازمجلس بیرون روند و با یکدیگر مشورت کرده، گفتند"},{"v":16,"t":"که «با این دو شخص چه کنیم؟ زیرا که برجمیع سکنه اورشلیم واضح شد که معجزه‌ای آشکار از ایشان صادر گردید و نمی توانیم انکار کرد."},{"v":17,"t":"لیکن تا بیشتر در میان قوم شیوع نیابد، ایشان را سخت تهدید کنیم که دیگر با هیچ‌کس این اسم را به زبان نیاورند.»"},{"v":18,"t":"پس ایشان راخواسته قدغن کردند که هرگز نام عیسی را بر زبان نیاورند و تعلیم ندهند."},{"v":19,"t":"اما پطرس و یوحنا درجواب ایشان گفتند: «اگر نزد خدا صواب است که اطاعت شما را بر اطاعت خدا ترجیح دهیم حکم کنید."},{"v":20,"t":"زیرا که ما را امکان آن نیست که آنچه دیده و شنیده‌ایم، نگوییم.»"},{"v":21,"t":"و چون ایشان رازیاد تهدید نموده بودند، آزاد ساختند چونکه راهی نیافتند که ایشان را معذب سازند به‌سبب قوم زیرا همه به واسطه آن ماجرا خدا را تمجیدمی نمودند،"},{"v":22,"t":"زیرا آن شخص که معجزه شفا دراو پدید گشت، بیشتر از چهل ساله بود."},{"v":23,"t":"و چون رهایی یافتند، نزد رفقای خودرفتند و ایشان را از آنچه روسای کهنه و مشایخ بدیشان گفته بودند، مطلع ساختند."},{"v":24,"t":"چون این راشنیدند، آواز خود را به یکدل به خدا بلند کرده، گفتند: «خداوندا، تو آن خدا هستی که آسمان وزمین و دریا و آنچه در آنها است آفریدی،"},{"v":25,"t":"که بوسیله روح‌القدس به زبان پدر ما و بنده خودداود گفتی “چرا امت‌ها هنگامه می‌کنند و قومها به باطل می‌اندیشند؛"},{"v":26,"t":"سلاطین زمین برخاستند وحکام با هم مشورت کردند، برخلاف خداوند وبرخلاف مسیحش.”"},{"v":27,"t":"زیرا که فی الواقع بر بنده قدوس تو عیسی که او را مسح کردی، هیرودیس و پنطیوس پیلاطس با امت‌ها و قومهای اسرائیل با هم جمع شدند،"},{"v":28,"t":"تا آنچه را که دست و رای تو از قبل مقدر فرموده بود، به‌جا آورند."},{"v":29,"t":"و الان ای خداوند، به تهدیدات ایشان نظر کن و غلامان خود را عطا فرما تا به دلیری تمام به کلام تو سخن گویند،"},{"v":30,"t":"به دراز کردن دست خود، بجهت شفادادن و جاری کردن آیات و معجزات به نام بنده قدوس خود عیسی.»"},{"v":31,"t":"و چون ایشان دعا کرده بودند، مکانی که درآن جمع بودند به حرکت آمد و همه به روح‌القدس پر شده، کلام خدا را به دلیری می‌گفتند."},{"v":32,"t":"و جمله مومنین را یک دل و یک جان بود، بحدی که هیچ‌کس چیزی از اموال خودرا از آن خود نمی دانست، بلکه همه‌چیز رامشترک می‌داشتند."},{"v":33,"t":"و رسولان به قوت عظیم به قیامت عیسی خداوند شهادت می‌دادند و فیضی عظیم برهمگی ایشان بود."},{"v":34,"t":"زیرا هیچ‌کس از آن گروه محتاج نبود زیرا هر‌که صاحب زمین یا خانه بود، آنها را فروختند و قیمت مبیعات را آورده،"},{"v":35,"t":"به قدمهای رسولان می‌نهادند و به هر یک بقدراحتیاجش تقسیم می‌نمودند."},{"v":36,"t":"و یوسف که رسولان او را برنابا یعنی ابن الوعظ لقب دادند، مردی از سبط لاوی و از طایفه قپرسی،"},{"v":37,"t":"زمینی را که داشت فروخته، قیمت آن را آورد و پیش قدمهای رسولان گذارد."}],"en":[{"v":1,"t":"As they spoke to the people, the priests and the captain of the temple and the Sadducees came to them,"},{"v":2,"t":"being upset because they taught the people and proclaimed in Jesus the resurrection from the dead."},{"v":3,"t":"They laid hands on them, and put them in custody until the next day, for it was now evening."},{"v":4,"t":"But many of those who heard the word believed, and the number of the men came to be about five thousand."},{"v":5,"t":"In the morning, their rulers, elders, and scribes were gathered together in Jerusalem."},{"v":6,"t":"Annas the high priest was there, with Caiaphas, John, Alexander, and as many as were relatives of the high priest."},{"v":7,"t":"When they had stood Peter and John in the middle of them, they inquired, “By what power, or in what name, have you done this?”"},{"v":8,"t":"Then Peter, filled with the Holy Spirit, said to them, “You rulers of the people and elders of Israel,"},{"v":9,"t":"if we are examined today concerning a good deed done to a crippled man, by what means this man has been healed,"},{"v":10,"t":"may it be known to you all, and to all the people of Israel, that in the name of Jesus Christ of Nazareth, whom you crucified, whom God raised from the dead, this man stands here before you whole in him."},{"v":11,"t":"He is ‘the stone which was regarded as worthless by you, the builders, which has become the head of the corner.’"},{"v":12,"t":"There is salvation in no one else, for there is no other name under heaven that is given among men, by which we must be saved!”"},{"v":13,"t":"Now when they saw the boldness of Peter and John, and had perceived that they were unlearned and ignorant men, they marveled. They recognized that they had been with Jesus."},{"v":14,"t":"Seeing the man who was healed standing with them, they could say nothing against it."},{"v":15,"t":"But when they had commanded them to go aside out of the council, they conferred among themselves,"},{"v":16,"t":"saying, “What shall we do to these men? Because indeed a notable miracle has been done through them, as can be plainly seen by all who dwell in Jerusalem, and we can’t deny it."},{"v":17,"t":"But so that this spreads no further among the people, let’s threaten them, that from now on they don’t speak to anyone in this name.”"},{"v":18,"t":"They called them, and commanded them not to speak at all nor teach in the name of Jesus."},{"v":19,"t":"But Peter and John answered them, “Whether it is right in the sight of God to listen to you rather than to God, judge for yourselves,"},{"v":20,"t":"for we can’t help telling the things which we saw and heard.”"},{"v":21,"t":"When they had further threatened them, they let them go, finding no way to punish them, because of the people; for everyone glorified God for that which was done."},{"v":22,"t":"For the man on whom this miracle of healing was performed was more than forty years old."},{"v":23,"t":"Being let go, they came to their own company and reported all that the chief priests and the elders had said to them."},{"v":24,"t":"When they heard it, they lifted up their voice to God with one accord and said, “O Lord, you are God, who made the heaven, the earth, the sea, and all that is in them;"},{"v":25,"t":"who by the mouth of your servant David, said, ‘Why do the nations rage, and the peoples plot a vain thing?"},{"v":26,"t":"The kings of the earth take a stand, and the rulers plot together, against the Lord, and against his Christ.’"},{"v":27,"t":"“For truly, both Herod and Pontius Pilate, with the Gentiles and the people of Israel, were gathered together against your holy servant Jesus, whom you anointed,"},{"v":28,"t":"to do whatever your hand and your counsel foreordained to happen."},{"v":29,"t":"Now, Lord, look at their threats, and grant to your servants to speak your word with all boldness,"},{"v":30,"t":"while you stretch out your hand to heal; and that signs and wonders may be done through the name of your holy Servant Jesus.”"},{"v":31,"t":"When they had prayed, the place was shaken where they were gathered together. They were all filled with the Holy Spirit, and they spoke the word of God with boldness."},{"v":32,"t":"The multitude of those who believed were of one heart and soul. Not one of them claimed that anything of the things which he possessed was his own, but they had all things in common."},{"v":33,"t":"With great power, the apostles gave their testimony of the resurrection of the Lord Jesus. Great grace was on them all."},{"v":34,"t":"For neither was there among them any who lacked, for as many as were owners of lands or houses sold them, and brought the proceeds of the things that were sold,"},{"v":35,"t":"and laid them at the apostles’ feet; and distribution was made to each, according as anyone had need."},{"v":36,"t":"Joses, who by the apostles was also called Barnabas (which is, being interpreted, Son of Encouragement), a Levite, a man of Cyprus by race,"},{"v":37,"t":"having a field, sold it and brought the money and laid it at the apostles’ feet."}],"hr":[{"v":1,"t":"Dok su oni još govorili narodu, priđu im svećenici, hramski zapovjednik i saduceji,"},{"v":2,"t":"ozlovoljeni što uče narod i navješćuju - u Isusu - uskrsnuće od mrtvih;"},{"v":3,"t":"pograbe ih i bace u tamnicu do sutra jer već bijaše večer."},{"v":4,"t":"Ipak mnogi od onih koji su čuli Riječ, povjerovaše te broj vjernika poraste nekako do pet tisuća."},{"v":5,"t":"Sutradan se sastadoše u Jeruzalemu glavari, starješine i pismoznanci -"},{"v":6,"t":"i veliki svećenik Ana, i Kajfa, i Ivan, i Aleksandar, i svi od roda velikosvećeničkoga."},{"v":7,"t":"Izvedoše apostole preda se pa ih stadoše ispitivati: “Kojom snagom ili po kojem imenu vi to učiniste?”"},{"v":8,"t":"Onda Petar pun Duha Svetoga reče: “Glavari narodni i starješine!"},{"v":9,"t":"Zar mi danas odgovaramo zbog dobra djela učinjena bolesnu čovjeku? Po kome je ovaj spašen?"},{"v":10,"t":"Neka bude znano svima vama i svemu narodu Izraelovu: po imenu Isusa Krista Nazarećanina, kojega ste vi raspeli, a kojega Bog uskrisi od mrtvih! Po njemu ovaj stoji pred vama zdrav!"},{"v":11,"t":"On je onaj kamen koji vi graditelji odbaciste, ali koji postade kamen zaglavni."},{"v":12,"t":"I nema ni u kome drugom spasenja. Nema uistinu pod nebom drugoga imena dana ljudima po kojemu se možemo spasiti.”"},{"v":13,"t":"Kad vidješe neustrašivost Petrovu i Ivanovu, a znajući da su to ljudi nepismeni i neuki, bijahu u čudu; znali su ih, da bijahu s Isusom, ali"},{"v":14,"t":"videći gdje s njima stoji izliječeni čovjek, nisu mogli ništa protusloviti."},{"v":15,"t":"Stoga zapovjediše da izađu iz vijećnice pa stadoše raspravljati:"},{"v":16,"t":"“Što ćemo s tim ljudima? Ta učinili su očit znak, poznat svim Jeruzalemcima, ne možemo ga nijekati;"},{"v":17,"t":"ali da se još više ne razglasi u narod, zaprijetimo im da nikomu živom o tom Imenu više ne govore.”"},{"v":18,"t":"Pozvaše ih i zapovjediše im da podnipošto ne zbore niti naučavaju u ime Isusovo."},{"v":19,"t":"Ali im Petar i Ivan odgovoriše: “Sudite je li pred Bogom pravo slušati radije vas nego Boga."},{"v":20,"t":"Mi doista ne možemo ne govoriti što vidjesmo i čusmo.”"},{"v":21,"t":"Ali oni ne našavši kako da ih kazne, opet im zaprijete pa ih otpuste poradi naroda jer su svi slavili Boga zbog onoga što se dogodilo."},{"v":22,"t":"Jer čovjeku na kom se dogodi čudo ozdravljenja bijaše više od četrdeset godina."},{"v":23,"t":"Otpušteni, odoše svojima i javiše što im rekoše veliki svećenici i starješine."},{"v":24,"t":"Kad su oni to čuli, jednodušno podigoše glas k Bogu i rekoše: “Gospodine, ti si stvorio nebo i zemlju i more i sve što je u njima!"},{"v":25,"t":"Ti si na usta oca našega, sluge svoga Davida, po Duhu Svetom rekao: Zašto se bune narodi, zašto puci ludosti snuju?"},{"v":26,"t":"Ustaju kraljevi zemaljski, Knezovi se rotÄe protiv Gospodina i protiv Pomazanika njegova."},{"v":27,"t":"RotÄe se, uistinu, u ovome gradu na svetog Slugu tvoga Isusa, kog pomaza, rotÄe se Herod i Poncije Pilat zajedno s narodima i pucima izraelskim"},{"v":28,"t":"da učine što tvoja ruka i tvoja volja predodredi da se zbude."},{"v":29,"t":"I evo sada, Gospodine, promotri prijetnje njihove i daj slugama svojim sa svom smjelošću navješćivati riječ tvoju!"},{"v":30,"t":"Pruži ruku svoju da bude ozdravljenja, znamenja i čudesa po imenu svetoga Sluge tvoga Isusa.”"},{"v":31,"t":"I pošto se pomoliše, potrese se mjesto gdje bijahu sabrani, i svi se napuniše Duha Svetoga te stanu navješćivati riječ Božju smjelo."},{"v":32,"t":"U mnoštva onih što prigrliše vjeru bijaše jedno srce i jedna duša. I nijedan od njih nije svojim zvao ništa od onoga što je imao, nego im sve bijaše zajedničko."},{"v":33,"t":"Apostoli pak velikom silom davahu svjedočanstvo o uskrsnuću Gospodina Isusa i svi uživahu veliku naklonost."},{"v":34,"t":"Doista, nitko među njima nije oskudijevao jer koji bi god posjedovali zemljišta ili kuće, prodavali bi ih i utržak donosili"},{"v":35,"t":"i stavljali pred noge apostolima. A dijelilo se svakomu koliko je trebao."},{"v":36,"t":"A Josip, od apostola prozvan Barnaba, što znači Sin utjehe, levit, rodom Cipranin,"},{"v":37,"t":"posjedovaše jednu njivu; proda je pa donese novac i postavi pred noge apostolima."}]},"5":{"fa":[{"v":1,"t":"اما شخصی حنانیا نام، با زوجه‌اش سفیره ملکی فروخته،"},{"v":2,"t":"قدری از قیمت آن را به اطلاع زن خود نگاه داشت و قدری از آن راآورده، نزد قدمهای رسولان نهاد."},{"v":3,"t":"آنگاه پطرس گفت: «ای حنانیا چرا شیطان دل تو را پر ساخته است تا روح‌القدس را فریب دهی و مقداری ازقیمت زمین را نگاه داری؟"},{"v":4,"t":"آیا چون داشتی از آن تو نبود و چون فروخته شد در اختیار تو نبود؟ چرا این را در دل خود نهادی؟ به انسان دروغ نگفتی بلکه به خدا.»"},{"v":5,"t":"حنانیا چون این سخنان راشنید افتاده، جان بداد و خوفی شدید بر همه شنوندگان این چیزها مستولی گشت."},{"v":6,"t":"آنگاه جوانان برخاسته، او را کفن کردند و بیرون برده، دفن نمودند."},{"v":7,"t":"و تخمین سه ساعت گذشت که زوجه‌اش ازماجرا مطلع نشده درآمد."},{"v":8,"t":"پطرس بدو گفت: «مرابگو که آیا زمین را به همین قیمت فروختید؟» گفت: «بلی، به همین.»"},{"v":9,"t":"پطرس به وی گفت: «برای چه متفق شدید تا روح خداوند را امتحان کنید؟ اینک پایهای آنانی که شوهر تو را دفن کردند، بر آستانه است و تو را هم بیرون خواهندبرد.»"},{"v":10,"t":"در ساعت پیش قدمهای او افتاده، جان بداد و جوانان داخل شده، او را مرده یافتند. پس بیرون برده، به پهلوی شوهرش دفن کردند."},{"v":11,"t":"وخوفی شدید تمامی کلیسا و همه آنانی را که این را شنیدند، فرو گرفت."},{"v":12,"t":"و آیات و معجزات عظیمه از دستهای رسولان در میان قوم به ظهور می‌رسید و همه به یکدل در رواق سلیمان می‌بودند."},{"v":13,"t":"اما احدی ازدیگران جرات نمی کرد که بدیشان ملحق شود، لیکن خلق، ایشان را محترم می‌داشتند."},{"v":14,"t":"وبیشتر ایمانداران به خداوند متحد می‌شدند، انبوهی از مردان و زنان،"},{"v":15,"t":"بقسمی که مریضان رادر کوچه‌ها بیرون آوردند و بر بسترها و تختهاخوابانیدند تا وقتی که پطرس آید، اقلا سایه او بربعضی از ایشان بیفتد."},{"v":16,"t":"و گروهی از بلدان اطراف اورشلیم، بیماران و رنج دیدگان ارواح پلیده را آورده، جمع شدند و جمیع ایشان شفایافتند."},{"v":17,"t":"اما رئیس کهنه و همه رفقایش که از طایفه صدوقیان بودند، برخاسته، به غیرت پر گشتند"},{"v":18,"t":"و بر رسولان دست انداخته، ایشان را در زندان عام انداختند."},{"v":19,"t":"شبانگاه فرشته خداوند درهای زندان را باز کرده و ایشان را بیرون آورده، گفت:"},{"v":20,"t":"«بروید و در هیکل ایستاده، تمام سخنهای این حیات را به مردم بگویید."},{"v":21,"t":"چون این را شنیدند، وقت فجر به هیکل درآمده، تعلیم دادند."},{"v":22,"t":"پس خادمان رفته، ایشان را در زندان نیافتند و برگشته، خبر داده،"},{"v":23,"t":"گفتند که «زندان را به احتیاط تمام بسته یافتیم و پاسبانان را بیرون درها ایستاده، لیکن چون باز کردیم، هیچ‌کس را در آن نیافتیم.»"},{"v":24,"t":"چون کاهن و سردار سپاه هیکل و روسای کهنه این سخنان را شنیدند، درباره ایشان در حیرت افتادند که «این چه خواهد شد؟»"},{"v":25,"t":"آنگاه کسی آمده ایشان را آگاهانید که اینک آن کسانی که محبوس نمودید، در هیکل ایستاده، مردم راتعلیم می‌دهند."},{"v":26,"t":"پس سردار سپاه با خادمان رفته ایشان را آوردند، لیکن نه به زور زیرا که ازقوم ترسیدند که مبادا ایشان را سنگسار کنند."},{"v":27,"t":"و چون ایشان را به مجلس حاضر کرده، برپابداشتند، رئیس کهنه از ایشان پرسیده، گفت:"},{"v":28,"t":"«مگر شما را قدغن بلیغ نفرمودیم که بدین اسم تعلیم مدهید؟ همانا اورشلیم را به تعلیم خود پرساخته‌اید و می‌خواهید خون این مرد را به گردن ما فرود آرید.»"},{"v":29,"t":"پطرس و رسولان در جواب گفتند: «خدا را می‌باید بیشتر از انسان اطاعت نمود."},{"v":30,"t":"خدای پدران ما، آن عیسی را برخیزانیدکه شما به صلیب کشیده، کشتید."},{"v":31,"t":"او را خدا بردست راست خود بالا برده، سرور و نجات‌دهنده ساخت تا اسرائیل را توبه و آمرزش گناهان بدهد."},{"v":32,"t":"و ما هستیم شاهدان او بر این امور، چنانکه روح‌القدس نیز است که خدا او را به همه مطیعان او عطا فرموده است.»"},{"v":33,"t":"چون شنیدند دلریش گشته، مشورت کردند که ایشان را به قتل رسانند."},{"v":34,"t":"اما شخصی فریسی، غمالائیل نام که مفتی و نزد تمامی خلق محترم بود، در مجلس برخاسته، فرمود تارسولان را ساعتی بیرون برند."},{"v":35,"t":"پس ایشان راگفت: «ای مردان اسرائیلی، برحذر باشید از آنچه می‌خواهید با این اشخاص بکنید."},{"v":36,"t":"زیرا قبل ازاین ایام، تیودا نامی برخاسته، خود را شخصی می‌پنداشت و گروهی قریب به چهار صد نفر بدوپیوستند. او کشته شد و متابعانش نیز پراکنده ونیست گردیدند."},{"v":37,"t":"و بعد از او یهودای جلیلی درایام اسم نویسی خروج کرد و جمعی را در عقب خود کشید. او نیز هلاک شد و همه تابعان اوپراکنده شدند."},{"v":38,"t":"الان به شما می‌گویم از این مردم دست بردارید و ایشان را واگذارید زیرا اگراین رای و عمل از انسان باشد، خود تباه خواهد شد."},{"v":39,"t":"ولی اگر از خدا باشد، نمی توانید آن رابرطرف نمود مبادا معلوم شود که با خدا منازعه می‌کنید.»"},{"v":40,"t":"پس به سخن او رضا دادند و رسولان را حاضر ساخته، تازیانه زدند و قدغن نمودند که دیگر به نام عیسی حرف نزنند پس ایشان رامرخص کردند."},{"v":41,"t":"و ایشان از حضور اهل شوراشادخاطر رفتند از آنرو که شایسته آن شمرده شدند که بجهت اسم او رسوایی کشند"},{"v":42,"t":"و هرروزه در هیکل و خانه‌ها از تعلیم و مژده دادن که عیسی مسیح است دست نکشیدند."}],"en":[{"v":1,"t":"But a certain man named Ananias, with Sapphira his wife, sold a possession,"},{"v":2,"t":"and kept back part of the price, his wife also being aware of it, then brought a certain part and laid it at the apostles’ feet."},{"v":3,"t":"But Peter said, “Ananias, why has Satan filled your heart to lie to the Holy Spirit and to keep back part of the price of the land?"},{"v":4,"t":"While you kept it, didn’t it remain your own? After it was sold, wasn’t it in your power? How is it that you have conceived this thing in your heart? You haven’t lied to men, but to God.”"},{"v":5,"t":"Ananias, hearing these words, fell down and died. Great fear came on all who heard these things."},{"v":6,"t":"The young men arose and wrapped him up, and they carried him out and buried him."},{"v":7,"t":"About three hours later, his wife, not knowing what had happened, came in."},{"v":8,"t":"Peter answered her, “Tell me whether you sold the land for so much.” She said, “Yes, for so much.”"},{"v":9,"t":"But Peter asked her, “How is it that you have agreed together to tempt the Spirit of the Lord? Behold, the feet of those who have buried your husband are at the door, and they will carry you out.”"},{"v":10,"t":"She fell down immediately at his feet and died. The young men came in and found her dead, and they carried her out and buried her by her husband."},{"v":11,"t":"Great fear came on the whole assembly, and on all who heard these things."},{"v":12,"t":"By the hands of the apostles many signs and wonders were done among the people. They were all with one accord in Solomon’s porch."},{"v":13,"t":"None of the rest dared to join them; however, the people honored them."},{"v":14,"t":"More believers were added to the Lord, multitudes of both men and women."},{"v":15,"t":"They even carried out the sick into the streets and laid them on cots and mattresses, so that as Peter came by, at least his shadow might overshadow some of them."},{"v":16,"t":"The multitude also came together from the cities around Jerusalem, bringing sick people and those who were tormented by unclean spirits; and they were all healed."},{"v":17,"t":"But the high priest rose up, and all those who were with him (which is the sect of the Sadducees), and they were filled with jealousy"},{"v":18,"t":"and laid hands on the apostles, then put them in public custody."},{"v":19,"t":"But an angel of the Lord opened the prison doors by night, and brought them out and said,"},{"v":20,"t":"“Go stand and speak in the temple to the people all the words of this life.”"},{"v":21,"t":"When they heard this, they entered into the temple about daybreak and taught. But the high priest and those who were with him came and called the council together, with all the senate of the children of Israel, and sent to the prison to have them brought."},{"v":22,"t":"But the officers who came didn’t find them in the prison. They returned and reported,"},{"v":23,"t":"“We found the prison shut and locked, and the guards standing before the doors, but when we opened them, we found no one inside!”"},{"v":24,"t":"Now when the high priest, the captain of the temple, and the chief priests heard these words, they were very perplexed about them and what might become of this."},{"v":25,"t":"One came and told them, “Behold, the men whom you put in prison are in the temple, standing and teaching the people.”"},{"v":26,"t":"Then the captain went with the officers, and brought them without violence, for they were afraid that the people might stone them."},{"v":27,"t":"When they had brought them, they set them before the council. The high priest questioned them,"},{"v":28,"t":"saying, “Didn’t we strictly command you not to teach in this name? Behold, you have filled Jerusalem with your teaching, and intend to bring this man’s blood on us.”"},{"v":29,"t":"But Peter and the apostles answered, “We must obey God rather than men."},{"v":30,"t":"The God of our fathers raised up Jesus, whom you killed, hanging him on a tree."},{"v":31,"t":"God exalted him with his right hand to be a Prince and a Savior, to give repentance to Israel, and remission of sins."},{"v":32,"t":"We are his witnesses of these things; and so also is the Holy Spirit, whom God has given to those who obey him.”"},{"v":33,"t":"But they, when they heard this, were cut to the heart, and were determined to kill them."},{"v":34,"t":"But one stood up in the council, a Pharisee named Gamaliel, a teacher of the law, honored by all the people, and commanded to put the apostles out for a little while."},{"v":35,"t":"He said to them, “You men of Israel, be careful concerning these men, what you are about to do."},{"v":36,"t":"For before these days Theudas rose up, making himself out to be somebody; to whom a number of men, about four hundred, joined themselves. He was slain; and all, as many as obeyed him, were dispersed and came to nothing."},{"v":37,"t":"After this man, Judas of Galilee rose up in the days of the enrollment, and drew away some people after him. He also perished, and all, as many as obeyed him, were scattered abroad."},{"v":38,"t":"Now I tell you, withdraw from these men and leave them alone. For if this counsel or this work is of men, it will be overthrown."},{"v":39,"t":"But if it is of God, you will not be able to overthrow it, and you would be found even to be fighting against God!”"},{"v":40,"t":"They agreed with him. Summoning the apostles, they beat them and commanded them not to speak in the name of Jesus, and let them go."},{"v":41,"t":"They therefore departed from the presence of the council, rejoicing that they were counted worthy to suffer dishonor for Jesus’ name."},{"v":42,"t":"Every day, in the temple and at home, they never stopped teaching and preaching Jesus, the Christ."}],"hr":[{"v":1,"t":"Neki pak čovjek po imenu Ananija, zajedno sa svojom ženom Safirom proda imanje"},{"v":2,"t":"pa u dogovoru sa ženom odvoji nešto od utrška, a samo jedan dio donese i postavi pred noge apostolima."},{"v":3,"t":"Petar mu reče: “Ananija, zašto ti Sotona ispuni srce te si slagao Duhu Svetomu i odvojio od utrška imanja?"},{"v":4,"t":"Da je ostalo neprodano, ne bi li tvoje ostalo; i jednoć prodano, nije li u tvojoj vlasti? Zašto si se na takvo što odlučio? Nisi slagao ljudima, nego Bogu!”"},{"v":5,"t":"Kako Ananija ču te riječi, sruši se i izdahnu. I silan strah spopade sve koji su to čuli."},{"v":6,"t":"Nato ustanu mladići, poviju ga, iznesu i pokopaju."},{"v":7,"t":"Nakon otprilike tri sata uđe njegova žena ne znajući što se dogodilo."},{"v":8,"t":"Petar joj reče: “Reci mi, jeste li za toliko dali imanje?” Ona odgovori: “Da, za toliko.”"},{"v":9,"t":"A Petar će joj: “Što vam bi da se složiste iskušati Duha Gospodnjega? Eto na vratima nogu onih koji ti pokopaše muža! I tebe će iznijeti!”"},{"v":10,"t":"Ona se umah sruši do njegovih nogu i izdahnu. Oni mladići uđu, nađu je mrtvu, iznesu je i pokopaju uz muža."},{"v":11,"t":"I silan strah spopade cijelu Crkvu i sve koji su to čuli."},{"v":12,"t":"Po rukama se apostolskim događala mnoga znamenja i čudesa u narodu. Svi su se jednodušno okupljali u Trijemu Salomonovu."},{"v":13,"t":"Nitko se drugi nije usuđivao pridružiti im se, ali ih je narod veličao."},{"v":14,"t":"I sve se više povećavalo mnoštvo muževa i žena što vjerovahu Gospodinu"},{"v":15,"t":"tako da su na trgove iznosili bolesnike i postavljali ih na ležaljkama i posteljama ne bi li, kad Petar bude prolazio, bar sjena njegova osjenila kojega od njih."},{"v":16,"t":"A slijegalo bi se i mnoštvo iz gradova oko Jeruzalema: donosili bi bolesnike i opsjednute od nečistih duhova, i svi bi ozdravljali."},{"v":17,"t":"Onda se podiže veliki svećenik i sve njegove pristaše - sljedba saducejska."},{"v":18,"t":"Puni zavisti, pohvataju apostole i strpaju ih u javnu tamnicu."},{"v":19,"t":"Ali anđeo Gospodnji noću otvori vrata tamnice, izvede ih i reče:"},{"v":20,"t":"“Pođite i postojano u Hramu navješćujte narodu sve riječi Života ovoga.”"},{"v":21,"t":"Poslušni, u praskozorje su ušli u Hram te naučavali. Uto stiže veliki svećenik i njegove pristaše, sazovu Vijeće i sve starješinstvo sinova Izraelovih pa pošalju u zatvor da ih dovedu."},{"v":22,"t":"Kad stražari stigoše onamo, ne nađoše ih u tamnici pa se vrate i jave:"},{"v":23,"t":"“Zatvor smo našli sa svom pomnjom zatvoren i čuvare na straži pred vratima, ali kad smo otvorili, nikoga unutra ne nađosmo.”"},{"v":24,"t":"Kad su hramski zapovjednik i veliki svećenici čuli te riječi, u nedoumici su se pitali što bi to moglo biti."},{"v":25,"t":"Nato netko pristigne i dojavi im: “Eno, ljudi koje baciste u tamnicu, u Hramu stoje i uče narod.”"},{"v":26,"t":"Tada zapovjednik sa stražarima ode te ih dovede - ne na silu jer se bojahu da ih narod ne kamenuje."},{"v":27,"t":"Dovedoše ih i privedoše pred Vijeće. Veliki ih svećenik zapita:"},{"v":28,"t":"“Nismo li vam strogo zabranili učiti u to Ime? A vi ste eto napunili Jeruzalem svojim naukom i hoćete na nas navući krv toga čovjeka.”"},{"v":29,"t":"Petar i apostoli odvrate: “Treba se većma pokoravati Bogu negoli ljudima!"},{"v":30,"t":"Bog otaca naših uskrisi Isusa kojega vi smakoste objesivši ga na drvo."},{"v":31,"t":"Njega Bog desnicom svojom uzvisi za Začetnika i Spasitelja da obraćenjem podari Izraela i oproštenjem grijeha."},{"v":32,"t":"I mi smo svjedoci tih događaja i Duh Sveti kojega dade Bog onima što mu se pokoravaju.”"},{"v":33,"t":"Nato se oni razgnjeviše i htjedoše ih ubiti."},{"v":34,"t":"Ali ustade u Vijeću neki farizej imenom Gamaliel, zakonoznanac, kojega je poštovao sav narod. On zapovjedi da ljude načas izvedu"},{"v":35,"t":"pa će vijećnicima: “Izraelci, dobro promislite što ćete s tim ljudima."},{"v":36,"t":"Ta prije nekog vremena podiže se Teuda tvrdeći da je netko, i uza nj prista oko četiri stotine ljudi. Bi smaknut i sve mu se pristaše razbjegoše i netragom ih nesta."},{"v":37,"t":"Nakon toga se u dane popisa podiže Juda Galilejac i odvuče narod za sobom. I on propade i sve mu se pristaše raspršiše."},{"v":38,"t":"I sad evo kanite se, velim vam, tih ljudi i otpustite ih. Jer ako je taj naum ili to djelo od ljudi, propast će;"},{"v":39,"t":"ako li je pak od Boga, nećete ga moći uništiti - da se i s Bogom u ratu ne nađete.” Poslušaju ga"},{"v":40,"t":"pa dozovu apostole, išibaju ih, zapovjede im da ne govore u ime Isusovo pa ih otpuste."},{"v":41,"t":"Oni pak odu ispred Vijeća radosni što bijahu dostojni podnijeti pogrde za Ime."},{"v":42,"t":"I svaki su dan u Hramu i po kućama neprestance učili i navješćivali Krista, Isusa."}]},"6":{"fa":[{"v":1,"t":"و در آن ایام چون شاگردان زیاد شدند، هلینستیان از عبرانیان شکایت بردند که بیوه‌زنان ایشان در خدمت یومیه بی‌بهره می‌ماندند."},{"v":2,"t":"پس آن دوازده، جماعت شاگردان راطلبیده، گفتند: «شایسته نیست که ما کلام خدا راترک کرده، مائده‌ها را خدمت کنیم."},{"v":3,"t":"لهذا‌ای برادران هفت نفر نیک نام و پر از روح‌القدس وحکمت را از میان خود انتخاب کنید تا ایشان را براین مهم بگماریم."},{"v":4,"t":"اما ما خود را به عبادت وخدمت کلام خواهیم سپرد.»"},{"v":5,"t":"پس تمام جماعت بدین سخن رضا دادند و استیفان مردی پر از ایمان و روح‌القدس و فیلپس و پروخرس و نیکانور وتیمون و پرمیناس و نیقولاوس جدید، از اهل انطاکیه را انتخاب کرده،"},{"v":6,"t":"ایشان را در حضوررسولان برپا بداشتند و دعا کرده، دست بر ایشان گذاشتند."},{"v":7,"t":"و کلام خدا ترقی نمود و عددشاگردان در اورشلیم بغایت می‌افزود و گروهی عظیم از کهنه مطیع ایمان شدند."},{"v":8,"t":"اما استیفان پر از فیض و قوت شده، آیات ومعجزات عظیمه در میان مردم از او ظاهر می‌شد."},{"v":9,"t":"و تنی چند از کنیسه‌ای که مشهور است به کنیسه لیبرتینیان و قیروانیان و اسکندریان و ازاهل قلیقیا و آسیا برخاسته، با استیفان مباحثه می‌کردند،"},{"v":10,"t":"و با آن حکمت و روحی که او سخن می‌گفت، یارای مکالمه نداشتند."},{"v":11,"t":"پس چند نفررا بر این داشتند که بگویند: «این شخص راشنیدیم که به موسی و خدا سخن کفرآمیزمی گفت.»"},{"v":12,"t":"پس قوم و مشایخ و کاتبان راشورانیده، بر سر وی تاختند و او را گرفتار کرده، به مجلس حاضر ساختند."},{"v":13,"t":"و شهود کذبه برپاداشته، گفتند که «این شخص از گفتن سخن کفرآمیز بر این مکان مقدس و تورات دست برنمی دارد."},{"v":14,"t":"زیرا او را شنیدیم که می‌گفت این عیسی ناصری این مکان را تباه سازد و رسومی راکه موسی به ما سپرد، تغییر خواهد داد.»"},{"v":15,"t":"و همه کسانی که در مجلس حاضر بودند، بر او چشم دوخته، صورت وی را مثل صورت فرشته دیدند."}],"en":[{"v":1,"t":"Now in those days, when the number of the disciples was multiplying, a complaint arose from the Hellenists against the Hebrews, because their widows were neglected in the daily service."},{"v":2,"t":"The twelve summoned the multitude of the disciples and said, “It is not appropriate for us to forsake the word of God and serve tables."},{"v":3,"t":"Therefore, select from among you, brothers, seven men of good report, full of the Holy Spirit and of wisdom, whom we may appoint over this business."},{"v":4,"t":"But we will continue steadfastly in prayer and in the ministry of the word.”"},{"v":5,"t":"These words pleased the whole multitude. They chose Stephen, a man full of faith and of the Holy Spirit, Philip, Prochorus, Nicanor, Timon, Parmenas, and Nicolaus, a proselyte of Antioch,"},{"v":6,"t":"whom they set before the apostles. When they had prayed, they laid their hands on them."},{"v":7,"t":"The word of God increased and the number of the disciples greatly multiplied in Jerusalem. A great company of the priests were obedient to the faith."},{"v":8,"t":"Stephen, full of faith and power, performed great wonders and signs among the people."},{"v":9,"t":"But some of those who were of the synagogue called “The Libertines”, and of the Cyrenians, of the Alexandrians, and of those of Cilicia and Asia arose, disputing with Stephen."},{"v":10,"t":"They weren’t able to withstand the wisdom and the Spirit by which he spoke."},{"v":11,"t":"Then they secretly induced men to say, “We have heard him speak blasphemous words against Moses and God.”"},{"v":12,"t":"They stirred up the people, the elders, and the scribes, and came against him and seized him, then brought him in to the council,"},{"v":13,"t":"and set up false witnesses who said, “This man never stops speaking blasphemous words against this holy place and the law."},{"v":14,"t":"For we have heard him say that this Jesus of Nazareth will destroy this place, and will change the customs which Moses delivered to us.”"},{"v":15,"t":"All who sat in the council, fastening their eyes on him, saw his face like it was the face of an angel."}],"hr":[{"v":1,"t":"U one dane, kako se broj učenika množio, Židovi grčkog jezika stadoše mrmljati protiv domaćih Židova što se u svagdanjem služenju zanemaruju njihove udovice."},{"v":2,"t":"Dvanaestorica nato sazvaše mnoštvo učenika i rekoše: “Nije pravo da mi napustimo riječ Božju da bismo služili kod stolova."},{"v":3,"t":"De pronađite, braćo, između sebe sedam muževa na dobru glasu, punih Duha i mudrosti. Njih ćemo postaviti nad ovom službom,"},{"v":4,"t":"a mi ćemo se posvetiti molitvi i posluživanju Riječi.”"},{"v":5,"t":"Prijedlog se svidje svemu mnoštvu pa izabraše Stjepana, muža puna vjere i Duha Svetoga, zatim Filipa, Prohora, Nikanora, Timona, Parmenu te antiohijskog pridošlicu Nikolu."},{"v":6,"t":"Njih postave pred apostole, a oni pomolivši se, polože na njih ruke."},{"v":7,"t":"I riječ je Božja rasla, uvelike se množio broj učenika u Jeruzalemu i veliko je mnoštvo svećenika prihvaćalo vjeru."},{"v":8,"t":"Stjepan je pun milosti i snage činio velika čudesa i znamenja u narodu."},{"v":9,"t":"Nato se digoše neki iz takozvane sinagoge Slobodnjaka, Cirenaca, Aleksandrinaca te onih iz Cilicije i Azije pa počeše raspravljati sa Stjepanom,"},{"v":10,"t":"ali nisu mogli odoljeti mudrosti i Duhu kojim je govorio."},{"v":11,"t":"Onda podmetnuše neke ljude koji rekoše: “Čuli smo ga govoriti pogrdne riječi protiv Mojsija i Boga.”"},{"v":12,"t":"Podjare i narod, starješine i pismoznance pa priđu, zgrabe ga i odvuku u Vijeće."},{"v":13,"t":"Ondje namjestiše lažne svjedoke koji rekoše: “Ovaj čovjek neprestance govori protiv svetog Mjesta i Zakona."},{"v":14,"t":"Čuli smo ga doista govoriti: 'Isus Nazarećanin razvalit će ovo Mjesto i izmijeniti običaje koje nam predade Mojsije'.”"},{"v":15,"t":"A svi koji su sjedili u Vijeću upriješe pogled u Stjepana te opaziše - lice mu kao u anđela."}]},"7":{"fa":[{"v":1,"t":"آنگاه رئیس کهنه گفت: «آیا این امور چنین است؟»"},{"v":2,"t":"او گفت: «ای برادران و پدران، گوش دهید. خدای ذوالجلال بر پدر ما ابراهیم ظاهر شد وقتی که در جزیره بود قبل از توقفش در حران."},{"v":3,"t":"و بدوگفت: “از وطن خود و خویشانت بیرون شده، به زمینی که تو را نشان دهم برو.”"},{"v":4,"t":"پس از دیارکلدانیان روانه شده، در حران درنگ نمود؛ و بعداز وفات پدرش، او را کوچ داد به سوی این زمین که شما الان در آن ساکن می‌باشید."},{"v":5,"t":"و او را در این زمین میراثی، حتی بقدر جای پای خود نداد، لیکن وعده داد که آن را به وی و بعد از او به ذریتش به ملکیت دهد، هنگامی که هنوز اولادی نداشت."},{"v":6,"t":"و خدا گفت که “ذریت تو در ملک بیگانه، غریب خواهند بود و مدت چهار صد سال ایشان را به بندگی کشیده، معذب خواهندداشت.”"},{"v":7,"t":"و خدا گفت: “من بر آن طایفه‌ای که ایشان را مملوک سازند داوری خواهم نمود و بعداز آن بیرون آمده، در این مکان مرا عبادت خواهند نمود.”"},{"v":8,"t":"و عهد ختنه را به وی داد که بنابراین چون اسحاق را آورد، در روز هشتم او رامختون ساخت و اسحاق یعقوب را و یعقوب دوازده پطریارخ را."},{"v":9,"t":"«و پطریارخان به یوسف حسد برده، او را به مصر فروختند. اما خدا با وی می‌بود"},{"v":10,"t":"و او را ازتمامی زحمت او رستگار نموده، در حضورفرعون، پادشاه مصر توفیق و حکمت عطا فرمودتا او را بر مصر و تمام خاندان خود فرمان فرما قرارداد."},{"v":11,"t":"پس قحطی و ضیقی شدید بر همه ولایت مصر و کنعان رخ نمود، بحدی که اجداد ما قوتی نیافتند."},{"v":12,"t":"اما چون یعقوب شنید که در مصر غله یافت می‌شود، بار اول اجداد ما را فرستاد."},{"v":13,"t":"ودر کرت دوم یوسف خود را به برادران خودشناسانید و قبیله یوسف به نظر فرعون رسیدند."},{"v":14,"t":"پس یوسف فرستاده، پدر خود یعقوب و سایرعیالش را که هفتاد و پنج نفر بودند، طلبید."},{"v":15,"t":"پس یعقوب به مصر فرود آمده، او و اجداد ما وفات یافتند."},{"v":16,"t":"و ایشان را به شکیم برده، در مقبره‌ای که ابراهیم از بنی حمور، پدر شکیم به مبلغی خریده بود، دفن کردند."},{"v":17,"t":"«و چون هنگام وعده‌ای که خدا با ابراهیم قسم خورده بود نزدیک شد، قوم در مصر نموکرده، کثیر می‌گشتند."},{"v":18,"t":"تا وقتی که پادشاه دیگرکه یوسف را نمی شناخت برخاست."},{"v":19,"t":"او با قوم ما حیله نموده، اجداد ما را ذلیل ساخت تا اولادخود را بیرون انداختند تا زیست نکنند."},{"v":20,"t":"در آن وقت موسی تولد یافت وبغایت جمیل بوده، مدت سه ماه در خانه پدر خود پرورش یافت."},{"v":21,"t":"و چون او را بیرون افکندند، دختر فرعون او رابرداشته، برای خود به فرزندی تربیت نمود."},{"v":22,"t":"وموسی در تمامی حکمت اهل مصر تربیت یافته، در قول و فعل قوی گشت."},{"v":23,"t":"چون چهل سال ازعمر وی سپری گشت، به‌خاطرش رسید که ازبرادران خود، خاندان اسرائیل تفقد نماید."},{"v":24,"t":"وچون یکی را مظلوم دید او را حمایت نمود وانتقام آن عاجز را کشیده، آن مصری را بکشت."},{"v":25,"t":"پس گمان برد که بردرانش خواهند فهمید که خدا به‌دست او ایشان را نجات خواهد داد. امانفهمیدند."},{"v":26,"t":"و در فردای آن روز خود را به دو نفراز ایشان که منازعه می‌نمودند، ظاهر کرد وخواست مابین ایشان مصالحه دهد. پس گفت: “ای مردان، شما برادر می‌باشید. به یکدیگر چرا ظلم می‌کنید؟”"},{"v":27,"t":"آنگاه آنکه بر همسایه خودتعدی می‌نمود، او را رد کرده، گفت: “که تو را بر ماحاکم و داور ساخت؟"},{"v":28,"t":"آیا می‌خواهی مرابکشی چنانکه آن مصری را دیروز کشتی؟”"},{"v":29,"t":"پس موسی از این سخن فرار کرده، در زمین مدیان غربت اختیار کرد و در آنجا دو پسر آورد."},{"v":30,"t":"و چون چهل سال گذشت، در بیابان کوه سینا، فرشته خداوند در شعله آتش از بوته به وی ظاهر شد."},{"v":31,"t":"موسی چون این را دید از آن رویا درعجب شد و چون نزدیک می‌آمد تا نظر کند، خطاب از خداوند به وی رسید"},{"v":32,"t":"که “منم خدای پدرانت، خدای ابراهیم و خدای اسحاق و خدای یعقوب.” آنگاه موسی به لرزه درآمده، جسارت نکرد که نظر کند."},{"v":33,"t":"خداوند به وی گفت: “نعلین از پایهایت بیرون کن زیرا جایی که در آن ایستاده‌ای، زمین مقدس است."},{"v":34,"t":"همانا مشقت قوم خود را که در مصرند دیدم و ناله ایشان راشنیدم و برای رهانیدن ایشان نزول فرمودم. الحال بیا تا تو را به مصر فرستم.”"},{"v":35,"t":"همان موسی را که رد کرده، گفتند: “که تو را حاکم و داورساخت؟” خدا حاکم و نجات‌دهنده مقرر فرموده، به‌دست فرشته‌ای که در بوته بر وی ظاهر شد، فرستاد."},{"v":36,"t":"او با معجزات و آیاتی که مدت چهل سال در زمین مصر و بحر قلزم و صحرا به ظهورمی آورد، ایشان را بیرون آورد."},{"v":37,"t":"این همان موسی است که به بنی‌اسرائیل گفت: “خدا نبی‌ای را مثل من از میان برادران شما برای شما مبعوث خواهد کرد. سخن او را بشنوید.”"},{"v":38,"t":"همین است آنکه در جماعت در صحرا باآن فرشته‌ای که در کوه سینا بدو سخن می‌گفت وبا پدران ما بود و کلمات زنده را یافت تا به مارساند،"},{"v":39,"t":"که پدران ما نخواستند او را مطیع شوندبلکه او را رد کرده، دلهای خود را به سوی مصرگردانیدند،"},{"v":40,"t":"و به هارون گفتند: “برای ما خدایان ساز که در‌پیش ما بخرامند زیرا این موسی که ما رااز زمین مصر برآورد، نمی دانیم او را چه شده است.”"},{"v":41,"t":"پس در آن ایام گوساله‌ای ساختند وبدان بت قربانی گذرانیده به اعمال دستهای خودشادی کردند."},{"v":42,"t":"از این جهت خدا رو گردانیده، ایشان را واگذاشت تا جنود آسمان را پرستش نمایند، چنانکه در صحف انبیا نوشته شده است که “ای خاندان اسرائیل، آیا مدت چهل سال دربیابان برای من قربانی‌ها و هدایا گذرانیدید؟"},{"v":43,"t":"وخیمه ملوک و کوکب، خدای خود رمفان رابرداشتید یعنی اصنامی را که ساختید تا آنها راعبادت کنید. پس شما را بدان طرف بابل منتقل سازم.”"},{"v":44,"t":"و خیمه شهادت با پدران ما در صحرابود چنانکه امر فرموده، به موسی گفت: “آن رامطابق نمونه‌ای که دیده‌ای بساز.”"},{"v":45,"t":"و آن را اجداد ما یافته، همراه یوشع درآوردند به ملک امت هایی که خدا آنها را ازپیش روی پدران ما بیرون افکند تا ایام داود."},{"v":46,"t":"که او در حضور خدا مستفیض گشت و درخواست نمود که خود مسکنی برای خدای یعقوب پیدانماید."},{"v":47,"t":"اما سلیمان برای او خانه‌ای بساخت."},{"v":48,"t":"و لیکن حضرت اعلی در خانه های مصنوع دستها ساکن نمی شود چنانکه نبی گفته است"},{"v":49,"t":"که “خداوند می‌گوید آسمان کرسی من است وزمین پای انداز من. چه خانه‌ای برای من بنامی کنید و محل آرامیدن من کجاست؟"},{"v":50,"t":"مگردست من جمیع این چیزها را نیافرید.”"},{"v":51,"t":"‌ای گردنکشان که به دل و گوش نامختونید، شما پیوسته با روح‌القدس مقاومت می‌کنید، چنانکه پدران شما همچنین شما."},{"v":52,"t":"کیست ازانبیا که پدران شما بدو جفا نکردند؟ و آنانی راکشتند که از آمدن آن عادلی که شما بالفعل تسلیم کنندگان و قاتلان او شدید، پیش اخبارنمودند."},{"v":53,"t":"شما که به توسط فرشتگان شریعت رایافته، آن را حفظ نکردید!»"},{"v":54,"t":"چون این را شنیدند دلریش شده، بر وی دندانهای خود را فشردند."},{"v":55,"t":"اما او از روح‌القدس پر بوده، به سوی آسمان نگریست و جلال خدا رادید و عیسی را بدست راست خدا ایستاده وگفت:"},{"v":56,"t":"«اینک آسمان را گشاده، و پسر انسان رابه‌دست راست خدا ایستاده می‌بینم.»"},{"v":57,"t":"آنگاه به آواز بلند فریاد برکشیدند و گوشهای خود راگرفته، به یکدل بر او حمله کردند،"},{"v":58,"t":"و از شهربیرون کشیده، سنگسارش کردند. و شاهدان، جامه های خود را نزد پایهای جوانی که سولس نام داشت گذاردند."},{"v":59,"t":"و چون استیفان را سنگسارمی کردند، او دعا نموده، گفت: «ای عیسی خداوند، روح مرا بپذیر.»"},{"v":60,"t":"پس زانو زده، به آوازبلند ندا در‌داد که «خداوندا این گناه را بر اینهامگیر.» این را گفت و خوابید."}],"en":[{"v":1,"t":"The high priest said, “Are these things so?”"},{"v":2,"t":"He said, “Brothers and fathers, listen. The God of glory appeared to our father Abraham when he was in Mesopotamia, before he lived in Haran,"},{"v":3,"t":"and said to him, ‘Get out of your land and away from your relatives, and come into a land which I will show you.’"},{"v":4,"t":"Then he came out of the land of the Chaldaeans and lived in Haran. From there, when his father was dead, God moved him into this land where you are now living."},{"v":5,"t":"He gave him no inheritance in it, no, not so much as to set his foot on. He promised that he would give it to him for a possession, and to his offspring after him, when he still had no child."},{"v":6,"t":"God spoke in this way: that his offspring would live as aliens in a strange land, and that they would be enslaved and mistreated for four hundred years."},{"v":7,"t":"‘I will judge the nation to which they will be in bondage,’ said God, ‘and after that they will come out and serve me in this place.’"},{"v":8,"t":"He gave him the covenant of circumcision. So Abraham became the father of Isaac, and circumcised him the eighth day. Isaac became the father of Jacob, and Jacob became the father of the twelve patriarchs."},{"v":9,"t":"“The patriarchs, moved with jealousy against Joseph, sold him into Egypt. God was with him"},{"v":10,"t":"and delivered him out of all his afflictions, and gave him favor and wisdom before Pharaoh, king of Egypt. He made him governor over Egypt and all his house."},{"v":11,"t":"Now a famine came over all the land of Egypt and Canaan, and great affliction. Our fathers found no food."},{"v":12,"t":"But when Jacob heard that there was grain in Egypt, he sent out our fathers the first time."},{"v":13,"t":"On the second time Joseph was made known to his brothers, and Joseph’s family was revealed to Pharaoh."},{"v":14,"t":"Joseph sent and summoned Jacob his father and all his relatives, seventy-five souls."},{"v":15,"t":"Jacob went down into Egypt and he died, himself and our fathers;"},{"v":16,"t":"and they were brought back to Shechem and laid in the tomb that Abraham bought for a price in silver from the children of Hamor of Shechem."},{"v":17,"t":"“But as the time of the promise came close which God had sworn to Abraham, the people grew and multiplied in Egypt,"},{"v":18,"t":"until there arose a different king who didn’t know Joseph."},{"v":19,"t":"The same took advantage of our race and mistreated our fathers, and forced them to abandon their babies, so that they wouldn’t stay alive."},{"v":20,"t":"At that time Moses was born, and was exceedingly handsome to God. He was nourished three months in his father’s house."},{"v":21,"t":"When he was abandoned, Pharaoh’s daughter took him up and reared him as her own son."},{"v":22,"t":"Moses was instructed in all the wisdom of the Egyptians. He was mighty in his words and works."},{"v":23,"t":"But when he was forty years old, it came into his heart to visit his brothers, the children of Israel."},{"v":24,"t":"Seeing one of them suffer wrong, he defended him and avenged him who was oppressed, striking the Egyptian."},{"v":25,"t":"He supposed that his brothers understood that God, by his hand, was giving them deliverance; but they didn’t understand."},{"v":26,"t":"“The day following, he appeared to them as they fought, and urged them to be at peace again, saying, ‘Sirs, you are brothers. Why do you wrong one another?’"},{"v":27,"t":"But he who did his neighbor wrong pushed him away, saying, ‘Who made you a ruler and a judge over us?"},{"v":28,"t":"Do you want to kill me as you killed the Egyptian yesterday?’"},{"v":29,"t":"Moses fled at this saying, and became a stranger in the land of Midian, where he became the father of two sons."},{"v":30,"t":"“When forty years were fulfilled, an angel of the Lord appeared to him in the wilderness of Mount Sinai, in a flame of fire in a bush."},{"v":31,"t":"When Moses saw it, he wondered at the sight. As he came close to see, the voice of the Lord came to him,"},{"v":32,"t":"‘I am the God of your fathers: the God of Abraham, the God of Isaac, and the God of Jacob.’ Moses trembled and dared not look."},{"v":33,"t":"The Lord said to him, ‘Take off your sandals, for the place where you stand is holy ground."},{"v":34,"t":"I have surely seen the affliction of my people who are in Egypt, and have heard their groaning. I have come down to deliver them. Now come, I will send you into Egypt.’"},{"v":35,"t":"“This Moses whom they refused, saying, ‘Who made you a ruler and a judge?’—God has sent him as both a ruler and a deliverer by the hand of the angel who appeared to him in the bush."},{"v":36,"t":"This man led them out, having worked wonders and signs in Egypt, in the Red Sea, and in the wilderness for forty years."},{"v":37,"t":"This is that Moses who said to the children of Israel, ‘The Lord our God will raise up a prophet for you from among your brothers, like me.’"},{"v":38,"t":"This is he who was in the assembly in the wilderness with the angel that spoke to him on Mount Sinai, and with our fathers, who received living revelations to give to us,"},{"v":39,"t":"to whom our fathers wouldn’t be obedient, but rejected him and turned back in their hearts to Egypt,"},{"v":40,"t":"saying to Aaron, ‘Make us gods that will go before us, for as for this Moses who led us out of the land of Egypt, we don’t know what has become of him.’"},{"v":41,"t":"They made a calf in those days, and brought a sacrifice to the idol, and rejoiced in the works of their hands."},{"v":42,"t":"But God turned away and gave them up to serve the army of the sky, as it is written in the book of the prophets, ‘Did you offer to me slain animals and sacrifices forty years in the wilderness, O house of Israel?"},{"v":43,"t":"You took up the tabernacle of Moloch, the star of your god Rephan, the figures which you made to worship, so I will carry you away beyond Babylon.’"},{"v":44,"t":"“Our fathers had the tabernacle of the testimony in the wilderness, even as he who spoke to Moses commanded him to make it according to the pattern that he had seen;"},{"v":45,"t":"which also our fathers, in their turn, brought in with Joshua when they entered into the possession of the nations whom God drove out before the face of our fathers to the days of David,"},{"v":46,"t":"who found favor in the sight of God, and asked to find a habitation for the God of Jacob."},{"v":47,"t":"But Solomon built him a house."},{"v":48,"t":"However, the Most High doesn’t dwell in temples made with hands, as the prophet says,"},{"v":49,"t":"‘heaven is my throne, and the earth a footstool for my feet. What kind of house will you build me?’ says the Lord. ‘Or what is the place of my rest?"},{"v":50,"t":"Didn’t my hand make all these things?’"},{"v":51,"t":"“You stiff-necked and uncircumcised in heart and ears, you always resist the Holy Spirit! As your fathers did, so you do."},{"v":52,"t":"Which of the prophets didn’t your fathers persecute? They killed those who foretold the coming of the Righteous One, of whom you have now become betrayers and murderers."},{"v":53,"t":"You received the law as it was ordained by angels, and didn’t keep it!”"},{"v":54,"t":"Now when they heard these things, they were cut to the heart, and they gnashed at him with their teeth."},{"v":55,"t":"But he, being full of the Holy Spirit, looked up steadfastly into heaven and saw the glory of God, and Jesus standing on the right hand of God,"},{"v":56,"t":"and said, “Behold, I see the heavens opened and the Son of Man standing at the right hand of God!”"},{"v":57,"t":"But they cried out with a loud voice and stopped their ears, then rushed at him with one accord."},{"v":58,"t":"They threw him out of the city and stoned him. The witnesses placed their garments at the feet of a young man named Saul."},{"v":59,"t":"They stoned Stephen as he called out, saying, “Lord Jesus, receive my spirit!”"},{"v":60,"t":"He kneeled down and cried with a loud voice, “Lord, don’t hold this sin against them!” When he had said this, he fell asleep."}],"hr":[{"v":1,"t":"Veliki svećenik upita: “Je li to tako?”"},{"v":2,"t":"Stjepan odgovori: “Braćo i oci, čujte! Bog slave ukaza se ocu našemu Abrahamu dok bijaše u Mezopotamiji, prije negoli se nastani u Haranu,"},{"v":3,"t":"i reče mu: Iziđi iz zemlje svoje, iz zavičaja svoga, hajde u zemlju koju ću ti pokazati."},{"v":4,"t":"On nato iziđe iz zemlje kaldejske i nastani se u Haranu. Odande ga nakon smrti oca njegova Bog preseli u ovu zemlju u kojoj vi sada boravite."},{"v":5,"t":"U njoj mu ne dade ni stope baštine, nego obeća dati je u posjed njemu i potomstvu njegovu nakon njega, premda još nije imao djeteta."},{"v":6,"t":"Bog isto tako reče da će potomci njegovi biti pridošlice u zemlji tuđoj, da će ih porobljavati i tlačiti četiri stotine godina."},{"v":7,"t":"Ali narod kojemu budu robovali ja ću suditi, reče Bog. A nakon toga izići će i iskazati mi štovanje na ovome mjestu."},{"v":8,"t":"Dade mu i Savez obrezanja. Tako rodi Izaka i obreza ga osmi dan, Izak Jakova, Jakov dvanaest rodozačetnika.”"},{"v":9,"t":"“Rodozačetnici pak, iz zavisti, Josipa predadoše u Egipat. Ali Bog bijaše s njim"},{"v":10,"t":"te ga izbavljaše iz svih nevolja, podari ga naklonošću i mudrošću pred faraonom, kraljem egipatskim koji ga postavi za upravitelja nad Egiptom i nad cijelim dvorom svojim."},{"v":11,"t":"Onda u cijeloj zemlji egipatskoj i kanaanskoj nasta glad i nevolja velika: oci naši ne mogahu naći hrane."},{"v":12,"t":"Kad Jakov doču da u Egiptu ima žita, posla onamo najprije oce naše."},{"v":13,"t":"Drugi se put Josip očitova braći svojoj pa faraon dozna za podrijetlo Josipovo."},{"v":14,"t":"Josip tada posla po Jakova, oca svoga, i svu rodbinu, sedamdeset i pet duša."},{"v":15,"t":"Jakov tako siđe u Egipat. I umrije on i oci naši."},{"v":16,"t":"Preneseni su u Sihem i položeni u grob koji je Abraham za srebro kupio od sinova Hamorovih u Sihemu.”"},{"v":17,"t":"“Kako se bližilo vrijeme obećanja koje Bog obreče Abrahamu, rastao je u Egiptu narod i množio se"},{"v":18,"t":"dok ondje ne zavlada drugi kralj koji nije poznavao Josipa."},{"v":19,"t":"Lukav prema rodu našemu, tlačio je on oce naše da bi djecu svoju izlagali da ne ostanu na životu."},{"v":20,"t":"U taj se čas rodi Mojsije. Bijaše božanski lijep. Tri je mjeseca hranjen u kući očinskoj,"},{"v":21,"t":"a onda, kad je bio izložen, prigrli ga kći faraonova i othrani sebi za sina."},{"v":22,"t":"Tako Mojsije, odgojen u svoj mudrosti egipatskoj, bijaše silan na riječima i djelima.”"},{"v":23,"t":"“Kad mu bijaše četrdeset godina, ponuka ga srce da pohodi braću svoju, sinove Izraelove."},{"v":24,"t":"I kad vidje kako je jednomu nanesena nepravda, suprotstavi se i osveti zlostavljenoga ubivši Egipćanina."},{"v":25,"t":"Mislio je da će braća njegova shvatiti kako će im Bog po njegovoj ruci pružiti spasenje, ali oni ne shvatiše."},{"v":26,"t":"Sutradan se pojavi pred onima koji su se tukli te ih stade nagovarati da se izmire: 'Ljudi, braća ste! Zašto zlostavljate jedan drugoga?'"},{"v":27,"t":"Ali ga onaj što je zlostavljao svoga bližnjega odbi riječima: Tko te postavi glavarom i sucem nad nama?"},{"v":28,"t":"Kaniš li ubiti i mene kao što si jučer ubio onog Egipćanina?"},{"v":29,"t":"Na te riječi pobježe Mojsije i skloni se u zemlju midjansku, gdje mu se rodiše dva sina.”"},{"v":30,"t":"“Nakon četrdeset godina ukaza mu se Anđeo u pustinji brda Sinaja u rasplamtjeloj vatri jednoga grma."},{"v":31,"t":"Opazivši to, zadivi se Mojsije viđenju. Dok je prilazio da bolje promotri, eto glasa Gospodnjega:"},{"v":32,"t":"Ja sam Bog Otaca tvojih, Bog Abrahamov, Izakov i Jakovljev. Sav preplašen, Mojsije se ne usudi pogledati."},{"v":33,"t":"A Gospodin će mu: Izuj obuću s nogu! Jer mjesto na kojem stojiš, sveto je tlo."},{"v":34,"t":"Vidio sam, vidio nevolju naroda svoga u Egiptu i uzdisaj mu čuo pa siđoh izbaviti ga. I sad hajde! Šaljem te u Egipat!”"},{"v":35,"t":"“Toga Mojsija - kojega su se odrekli rekavši: Tko te postavi glavarom i sucem? - toga im Bog kao glavara i otkupitelja posla po Anđelu koji mu se ukaza u grmu."},{"v":36,"t":"On ih izvede učinivši čudesa i znamenja u zemlji egipatskoj, u Crvenome moru i u pustinji kroz četrdeset godina."},{"v":37,"t":"To je onaj Mojsije koji reče sinovima Izraelovim: Proroka poput mene od vaše braće podići će vam Bog."},{"v":38,"t":"To je onaj koji za skupa u pustinji bijaše između Anđela što mu govoraše na brdu Sinaju i otaca naših; onaj koji je primio riječi životne da ih nama preda."},{"v":39,"t":"Njemu se ne htjedoše pokoriti oci naši, nego ga odbiše i u srcima se svojima vratiše u Egipat"},{"v":40,"t":"rekavši Aronu: 'Napravi nam bogove koji će ići pred nama! Ta ne znamo što se dogodi s tim Mojsijem koji nas izvede iz zemlje egipatske.'"},{"v":41,"t":"Tele načiniše u dane one, prinesoše žrtvu tom kumiru i veseljahu se djelima ruku svojih."},{"v":42,"t":"Bog se pak odvrati i prepusti ih da časte vojsku nebesku, kao što piše u Knjizi proročkoj: Prinosiste li mi žrtve i prinose četrdeset godina u pustinji, dome Izraelov?"},{"v":43,"t":"Poprimiste šator Molohov i zvijezdu boga Refana - likove koje napraviste da biste im se klanjali. Odvest ću vas stoga u progonstvo onkraj Babilona!”"},{"v":44,"t":"“Oci naši imahu u pustinji Šator svjedočanstva kako odredi Onaj koji reče Mojsiju da se on načini po praliku koji je vidio."},{"v":45,"t":"Taj su Šator preuzeli oci naši i pod Jošuom ga unijeli u posjed s kojega Bog pred licem njihovim rastjera narode. Tako bijaše sve do dana Davida,"},{"v":46,"t":"koji je našao milost pred Bogom te molio da nađe boravište Bogu Jakovljevu."},{"v":47,"t":"Istom Salomon izgradi mu Dom."},{"v":48,"t":"Ali Svevišnji u rukotvorinama ne prebiva, kao što veli prorok:"},{"v":49,"t":"Nebesa su moje prijestolje, a zemlja podnožje nogama. Kakav dom da mi sagradite, govori Gospodin, i gdje da bude mjesto mog počinka?"},{"v":50,"t":"Nije li ruka moja načinila sve to?"},{"v":51,"t":"Tvrdovrati i neobrezanih srdaca i ušiju, vi se uvijek opirete Duhu Svetomu: kako oci vaši tako i vi!"},{"v":52,"t":"Kojega od proroka nisu progonili oci vaši? I pobiše one koji su unaprijed navijestili dolazak Pravednika čiji ste vi sada izdajice i ubojice,"},{"v":53,"t":"vi koji po anđeoskim uredbama primiste Zakon, ali ga se niste držali.”"},{"v":54,"t":"Kad su to čuli, uskipješe u srcima i počeše škripati zubima na njega."},{"v":55,"t":"Ali on, pun Duha Svetoga, uprije pogled u nebo i ugleda slavu Božju i Isusa gdje stoji zdesna Bogu"},{"v":56,"t":"pa reče: “Evo vidim nebesa otvorena i Sina Čovječjega gdje stoji zdesna Bogu.”"},{"v":57,"t":"Vičući iza glasa, oni zatisnuše uši i navališe jednodušno na njega."},{"v":58,"t":"Izbaciše ga iz grada pa ga kamenovahu. Svjedoci odložiše haljine do nogu mladića koji se zvao Savao."},{"v":59,"t":"I dok su ga kamenovali, Stjepan je zazivao: “Gospodine Isuse, primi duh moj!”"},{"v":60,"t":"Onda se baci na koljena i povika iza glasa: “Gospodine, ne uzmi im ovo za grijeh!” Kada to reče, usnu."}]},"8":{"fa":[{"v":1,"t":"می بود."},{"v":2,"t":"و مردان صالح استیفان را دفن کرده، برای وی ماتم عظیمی برپا داشتند."},{"v":3,"t":"اما سولس کلیسا رامعذب می‌ساخت و خانه به خانه گشته، مردان وزنان را برکشیده، به زندان می‌افکند."},{"v":4,"t":"پس آنانی که متفرق شدند، به هر جایی که می‌رسیدند به کلام بشارت می‌دادند."},{"v":5,"t":"اما فیلپس به بلدی از سامره درآمده، ایشان را به مسیح موعظه می‌نمود."},{"v":6,"t":"و مردم به یکدل به سخنان فیلپس گوش دادند، چون معجزاتی را که از اوصادر می‌گشت، می‌شنیدند و می‌دیدند،"},{"v":7,"t":"زیرا که ارواح پلید از بسیاری که داشتند نعره زده، بیرون می‌شدند ومفلوجان و لنگان بسیار شفا می‌یافتند."},{"v":8,"t":"و شادی عظیم در آن شهر روی نمود."},{"v":9,"t":"اما مردی شمعون نام قبل از آن در آن قریه بود که جادوگری می‌نمود و اهل سامره را متحیرمی ساخت و خود را شخصی بزرگ می‌نمود،"},{"v":10,"t":"بحدی که خرد و بزرگ گوش داده، می‌گفتند: «این است قوت عظیم خدا.»"},{"v":11,"t":"و بدو گوش دادنداز آنرو که مدت مدیدی بود از جادوگری اومتحیر می‌شدند."},{"v":12,"t":"لیکن چون به بشارت فیلپس که به ملکوت خدا و نام عیسی مسیح می‌داد، ایمان آوردند، مردان و زنان تعمید یافتند."},{"v":13,"t":"وشمعون نیز خود ایمان آورد و چون تعمید یافت همواره با فیلپس می‌بود و از دیدن آیات و قوات عظیمه که از او ظاهر می‌شد، در حیرت افتاد."},{"v":14,"t":"اما رسولان که در اورشلیم بودند، چون شنیدند که اهل سامره کلام خدا را پذیرفته‌اند، پطرس و یوحنا را نزد ایشان فرستادند."},{"v":15,"t":"وایشان آمده، بجهت ایشان دعا کردند تاروح‌القدس را بیابند،"},{"v":16,"t":"زیرا که هنوز بر هیچ‌کس از ایشان نازل نشده بود که به نام خداوند عیسی تعمید یافته بودند و بس."},{"v":17,"t":"پس دستها بر ایشان گذارده، روح‌القدس را یافتند."},{"v":18,"t":"اما شمعون چون دید که محض گذاردن دستهای رسولان روح‌القدس عطا می‌شود، مبلغی پیش ایشان آورده،"},{"v":19,"t":"گفت: «مرا نیز این قدرت دهید که به هرکس دست گذارم، روح‌القدس را بیابد.»"},{"v":20,"t":"پطرس بدو گفت: «زرت با تو هلاک باد، چونکه پنداشتی که عطای خدا به زر حاصل می‌شود."},{"v":21,"t":"تو را دراین امر، قسمت و بهره‌ای نیست زیرا که دلت درحضور خدا راست نمی باشد."},{"v":22,"t":"پس از این شرارت خود توبه کن و از خدا درخواست کن تاشاید این فکر دلت آمرزیده شود،"},{"v":23,"t":"زیرا که تو رامی بینم در زهره تلخ و قید شرارت گرفتاری.»"},{"v":24,"t":"شمعون در جواب گفت: «شما برای من به خداوند دعا کنید تا چیزی از آنچه گفتید بر من عارض نشود.»"},{"v":25,"t":"پس ارشاد نموده و به کلام خداوند تکلم کرده، به اورشلیم برگشتند و دربسیاری از بلدان اهل سامره بشارت دادند."},{"v":26,"t":"اما فرشته خداوند به فیلپس خطاب کرده، گفت: «برخیز و به‌جانب جنوب، به راهی که ازاورشلیم به سوی غزه می‌رود که صحراست، روانه شو.»"},{"v":27,"t":"پس برخاسته، روانه شد که ناگاه شخصی حبشی که خواجه‌سرا و مقتدر نزدکنداکه، ملکه حبش، و بر تمام خزانه او مختاربود، به اورشلیم بجهت عبادت آمده بود."},{"v":28,"t":"و درمراجعت بر ارابه خود نشسته، صحیفه اشعیای نبی را مطالعه می‌کند"},{"v":29,"t":"آنگاه روح به فیلپس گفت: «پیش برو و با آن ارابه همراه باش.»"},{"v":30,"t":"فیلپس پیش دویده، شنید که اشعیای نبی رامطالعه می‌کند. گفت: «آیا می‌فهمی آنچه رامی خوانی؟»"},{"v":31,"t":"گفت: «چگونه می‌توانم؟ مگرآنکه کسی مرا هدایت کند.» و از فیلپس خواهش نمود که سوار شده، با او بنشیند."},{"v":32,"t":"و فقره‌ای ازکتاب که می‌خواند این بود که «مثل گوسفندی که به مذبح برند و چون بره‌ای خاموش نزد پشم برنده خود، همچنین دهان خود را نمی گشاید."},{"v":33,"t":"درفروتنی او انصاف از او منقطع شد و نسب او را که می‌تواند تقریر کرد؟ زیرا که حیات او از زمین برداشته می‌شود.»"},{"v":34,"t":"پس خواجه‌سرا به فیلپس ملتفت شده، گفت: «از تو سوال می‌کنم که نبی این را درباره که می‌گوید؟ درباره خود یا درباره کسی دیگر؟»"},{"v":35,"t":"آنگاه فیلپس زبان خود را گشود و ازآن نوشته شروع کرده، وی را به عیسی بشارت داد."},{"v":36,"t":"و چون در عرض راه به آبی رسیدند، خواجه گفت: «اینک آب است! از تعمید یافتنم چه چیز مانع می‌باشد؟»"},{"v":37,"t":"فیلپس گفت: «هر گاه به تمام دل ایمان آوردی، جایز است.» او درجواب گفت: «ایمان آوردم که عیسی مسیح پسرخداست.»"},{"v":38,"t":"پس حکم کرد تا ارابه را نگاه دارندو فیلپس با خواجه‌سرا هر دو به آب فرود شدند. پس او را تعمید داد."},{"v":39,"t":"و چون از آب بالا آمدند، روح خداوند فیلپس را برداشته، خواجه‌سرا دیگراو را نیافت زیرا که راه خود را به خوشی پیش گرفت."},{"v":40,"t":"اما فیلپس در اشدود پیدا شد و در همه شهرها گشته بشارت می‌داد تا به قیصریه رسید."}],"en":[{"v":1,"t":"Saul was consenting to his death. A great persecution arose against the assembly which was in Jerusalem in that day. They were all scattered abroad throughout the regions of Judea and Samaria, except for the apostles."},{"v":2,"t":"Devout men buried Stephen and lamented greatly over him."},{"v":3,"t":"But Saul ravaged the assembly, entering into every house and dragged both men and women off to prison."},{"v":4,"t":"Therefore those who were scattered abroad went around preaching the word."},{"v":5,"t":"Philip went down to the city of Samaria and proclaimed to them the Christ."},{"v":6,"t":"The multitudes listened with one accord to the things that were spoken by Philip when they heard and saw the signs which he did."},{"v":7,"t":"For unclean spirits came out of many of those who had them. They came out, crying with a loud voice. Many who had been paralyzed and lame were healed."},{"v":8,"t":"There was great joy in that city."},{"v":9,"t":"But there was a certain man, Simon by name, who used to practice sorcery in the city and amazed the people of Samaria, making himself out to be some great one,"},{"v":10,"t":"to whom they all listened, from the least to the greatest, saying, “This man is that great power of God.”"},{"v":11,"t":"They listened to him because for a long time he had amazed them with his sorceries."},{"v":12,"t":"But when they believed Philip preaching good news concerning God’s Kingdom and the name of Jesus Christ, they were baptized, both men and women."},{"v":13,"t":"Simon himself also believed. Being baptized, he continued with Philip. Seeing signs and great miracles occurring, he was amazed."},{"v":14,"t":"Now when the apostles who were at Jerusalem heard that Samaria had received the word of God, they sent Peter and John to them,"},{"v":15,"t":"who, when they had come down, prayed for them, that they might receive the Holy Spirit;"},{"v":16,"t":"for as yet he had fallen on none of them. They had only been baptized in the name of Christ Jesus."},{"v":17,"t":"Then they laid their hands on them, and they received the Holy Spirit."},{"v":18,"t":"Now when Simon saw that the Holy Spirit was given through the laying on of the apostles’ hands, he offered them money,"},{"v":19,"t":"saying, “Give me also this power, that whomever I lay my hands on may receive the Holy Spirit.”"},{"v":20,"t":"But Peter said to him, “May your silver perish with you, because you thought you could obtain the gift of God with money!"},{"v":21,"t":"You have neither part nor lot in this matter, for your heart isn’t right before God."},{"v":22,"t":"Repent therefore of this, your wickedness, and ask God if perhaps the thought of your heart may be forgiven you."},{"v":23,"t":"For I see that you are in the poison of bitterness and in the bondage of iniquity.”"},{"v":24,"t":"Simon answered, “Pray for me to the Lord, that none of the things which you have spoken happen to me.”"},{"v":25,"t":"They therefore, when they had testified and spoken the word of the Lord, returned to Jerusalem, and preached the Good News to many villages of the Samaritans."},{"v":26,"t":"Then an angel of the Lord spoke to Philip, saying, “Arise, and go toward the south to the way that goes down from Jerusalem to Gaza. This is a desert.”"},{"v":27,"t":"He arose and went; and behold, there was a man of Ethiopia, a eunuch of great authority under Candace, queen of the Ethiopians, who was over all her treasure, who had come to Jerusalem to worship."},{"v":28,"t":"He was returning and sitting in his chariot, and was reading the prophet Isaiah."},{"v":29,"t":"The Spirit said to Philip, “Go near, and join yourself to this chariot.”"},{"v":30,"t":"Philip ran to him, and heard him reading Isaiah the prophet, and said, “Do you understand what you are reading?”"},{"v":31,"t":"He said, “How can I, unless someone explains it to me?” He begged Philip to come up and sit with him."},{"v":32,"t":"Now the passage of the Scripture which he was reading was this, “He was led as a sheep to the slaughter. As a lamb before his shearer is silent, so he doesn’t open his mouth."},{"v":33,"t":"In his humiliation, his judgment was taken away. Who will declare His generation? For his life is taken from the earth.”"},{"v":34,"t":"The eunuch answered Philip, “Who is the prophet talking about? About himself, or about someone else?”"},{"v":35,"t":"Philip opened his mouth, and beginning from this Scripture, preached to him about Jesus."},{"v":36,"t":"As they went on the way, they came to some water; and the eunuch said, “Behold, here is water. What is keeping me from being baptized?”"},{"v":38,"t":"He commanded the chariot to stand still, and they both went down into the water, both Philip and the eunuch, and he baptized him."},{"v":39,"t":"When they came up out of the water, the Spirit of the Lord caught Philip away, and the eunuch didn’t see him any more, for he went on his way rejoicing."},{"v":40,"t":"But Philip was found at Azotus. Passing through, he preached the Good News to all the cities until he came to Caesarea."}],"hr":[{"v":1,"t":"Savao je pristao da se Stjepan smakne. U onaj dan navali velik progon na Crkvu u Jeruzalemu. Svi se osim apostola raspršiše po krajevima judejskim i samarijskim."},{"v":2,"t":"Bogobojazni su ljudi pokopali Stjepana i održali veliko žalovanje za njim."},{"v":3,"t":"Savao je pak pustošio Crkvu: ulazio je u kuće, odvlačio muževe i žene i predavao ih u tamnicu."},{"v":4,"t":"Oni dakle što su se raspršili obilazili su navješćujući Riječ."},{"v":5,"t":"Filip tako siđe u grad samarijski i stade im propovijedati Krista."},{"v":6,"t":"Mnoštvo je jednodušno prihvaćalo što je Filip govorio slušajući ga i gledajući znamenja koja je činio."},{"v":7,"t":"Doista, iz mnogih su opsjednutih izlazili nečisti duhovi vičući iza glasa, a ozdravljali su i mnogi uzeti i hromi."},{"v":8,"t":"Nasta tako velika radost u onome gradu."},{"v":9,"t":"Čovjek se neki, imenom Šimun, u gradu već duže bavio čarobnjaštvom i opčaravao narod tvrdeći da je neki veliki."},{"v":10,"t":"Priklanjalo mu se sve, malo i veliko, te govorilo: “Ovaj je Snaga Božja, zvana Velika.”"},{"v":11,"t":"A priklanjahu mu se jer ih je duže vremena opčaravao svojim vradžbinama."},{"v":12,"t":"Ali kad povjerovaše Filipu koji navješćivaše evanđelje o kraljevstvu Božjemu i o imenu Isusa Krista, krštavahu se - muževi i žene."},{"v":13,"t":"Povjerova i Šimun te se krsti i osta uz Filipa: bio je zanesen promatrajući znamenja i čudesa koja su se događala."},{"v":14,"t":"Kad su apostoli u Jeruzalemu čuli da je Samarija prigrlila riječ Božju, poslaše k njima Petra i Ivana."},{"v":15,"t":"Oni siđoše i pomoliše se za njih da bi primili Duha Svetoga."},{"v":16,"t":"Jer još ni na koga od njih ne bijaše sišao; bijahu samo kršteni u ime Gospodina Isusa."},{"v":17,"t":"Tada polagahu ruke na njih i oni primahu Duha Svetoga."},{"v":18,"t":"Kad Šimun vidje da se polaganjem ruku apostolskih daje Duh, ponudi apostolima novaca"},{"v":19,"t":"govoreći: “Dajte i meni tu moć da svatko na koga položim ruke primi Duha Svetoga.”"},{"v":20,"t":"Petar mu odvrati: “Novac tvoj zajedno s tobom propao kad si mislio dar Božji novcima steći!"},{"v":21,"t":"Nema tebi ovdje dijela ni udjela jer tvoje srce nije pravo pred Bogom!"},{"v":22,"t":"Obrati se od te opakosti svoje i moli Gospodina ne bi li ti se kako oprostila namisao srca tvoga."},{"v":23,"t":"Ta gledam te: žučju si gorak i nepravdom okovan.”"},{"v":24,"t":"Šimun odgovori: “Molite i vi za me Gospodina da me ne snađe ništa od toga što rekoste!”"},{"v":25,"t":"Oni pak pošto posvjedočiše i dorekoše riječ Gospodnju, vratiše se u Jeruzalem navješćujući evanđelje mnogim selima samarijskim."},{"v":26,"t":"Anđeo se Gospodnji obrati Filipu: “Ustani i pođi na jug putom što iz Jeruzalema silazi u Gazu; on je pust.”"},{"v":27,"t":"On usta i pođe. Odjednom eto nekog Etiopljanina, dvoranina, visokog dostojanstvenika kandake, kraljice etiopske koji bijaše nad svom njezinom riznicom."},{"v":28,"t":"Vraćao se iz Jeruzalema, kamo je bio pošao pokloniti se; sjeđaše na svojim kolima i čitaše proroka Izaiju."},{"v":29,"t":"Duh reče Filipu: “Pođi i pridruži se tim kolima!”"},{"v":30,"t":"Filip pritrča i ču gdje onaj čita Izaiju proroka pa će mu: “Razumiješ li što čitaš?”"},{"v":31,"t":"On odvrati: “Kako bih mogao ako me tko ne uputi?” Onda zamoli Filipa da se uspne i sjedne uza nj."},{"v":32,"t":"A čitao je ovaj odlomak Pisma: Ko ovcu na klanje odvedoše ga, ko janje nijemo pred onim što ga striže on ne otvara svojih usta."},{"v":33,"t":"U poniženju sud mu je uskraćen. Naraštaj njegov tko da opiše? Da, uklonjen je sa zemlje život njegov."},{"v":34,"t":"Dvoranin se obrati Filipu pa će mu: “Molim te, o kome to prorok govori? O sebi ili o kome drugom?"},{"v":35,"t":"Filip prozbori te mu, pošavši od toga Pisma, navijesti evanđelje: Isusa."},{"v":36,"t":"Putujući tako, stigoše do neke vode pa će dvoranin: “Evo vode! Što priječi da se krstim?”"},{"v":37,"t":"#"},{"v":38,"t":"Zapovjedi da kola stanu pa obojica, Filip i dvoranin, siđoše u vodu te ga Filip krsti."},{"v":39,"t":"A kad iziđoše iz vode, Duh Gospodnji ugrabi Filipa te ga dvoranin više ne vidje. On radosno nastavi svojim putom,"},{"v":40,"t":"a Filip se nađe u Azotu. I kako je prolazio, navješćivaše evanđelje svim gradovima dok ne stiže u Cezareju."}]},"9":{"fa":[{"v":1,"t":"اما سولس هنوز تهدید و قتل بر شاگردان خداوند همی دمید و نزد رئیس کهنه آمد،"},{"v":2,"t":"و از او نامه‌ها خواست به سوی کنایسی که دردمشق بود تا اگر کسی را از اهل طریقت خواه مردو خواه زن بیابد، ایشان را بند برنهاده، به اورشلیم بیاورد."},{"v":3,"t":"و در اثنای راه، چون نزدیک به دمشق رسید، ناگاه نوری از آسمان دور او درخشید"},{"v":4,"t":"و به زمین افتاده، آوازی شنید که بدو گفت: «ای شاول، شاول، برای چه بر من جفا می‌کنی؟»"},{"v":5,"t":"گفت: «خداوندا تو کیستی؟» خداوند گفت: «من آن عیسی هستم که تو بدو جفا می‌کنی."},{"v":6,"t":"لیکن برخاسته، به شهر برو که آنجا به تو گفته می‌شودچه باید کرد.»"},{"v":7,"t":"اما آنانی که همسفر او بودند، خاموش ایستادند چونکه آن صدا را شنیدند، لیکن هیچ‌کس را ندیدند."},{"v":8,"t":"پس سولس از زمین برخاسته، چون چشمان خود را گشود، هیچ‌کس را ندید و دستش را گرفته، او را به دمشق بردند،"},{"v":9,"t":"و سه روز نابینا بوده، چیزی نخورد و نیاشامید."},{"v":10,"t":"و در دمشق، شاگردی حنانیا نام بود که خداوند در رویا بدو گفت: «ای حنانیا!» عرض کرد: «خداوندا لبیک!»"},{"v":11,"t":"خداوند وی را گفت: «برخیز و به کوچه‌ای که آن را راست می‌نامند بشتاب و در خانه یهودا، سولس نام طرسوسی راطلب کن زیرا که اینک دعا می‌کند،"},{"v":12,"t":"و شخصی حنانیا نام را در خواب دیده است که آمده، بر اودست گذارد تا بینا گردد.»"},{"v":13,"t":"حنانیا جواب داد که «ای خداوند، درباره این شخص از بسیاری شنیده‌ام که به مقدسین تو در اورشلیم چه مشقتهارسانید،"},{"v":14,"t":"و در اینجا نیز از روسای کهنه قدرت دارد که هر‌که نام تو را بخواند، او را حبس کند.»"},{"v":15,"t":"خداوند وی را گفت: «برو زیرا که او ظرف برگزیده من است تا نام مرا پیش امت‌ها و سلاطین و بنی‌اسرائیل ببرد."},{"v":16,"t":"زیرا که من او را نشان خواهم داد که چقدر زحمتها برای نام من بایدبکشد.»"},{"v":17,"t":"پس حنانیا رفته، بدان خانه درآمد و دستهابر وی گذارده، گفت: «ای برادر شاول، خداوندیعنی عیسی که در راهی که می‌آمدی بر تو ظاهرگشت، مرا فرستاد تا بینایی بیابی و از روح‌القدس پر شوی.»"},{"v":18,"t":"در ساعت از چشمان او چیزی مثل فلس افتاده، بینایی یافت و برخاسته، تعمیدگرفت."},{"v":19,"t":"و غذا خورده، قوت گرفت و روزی چند با شاگردان در دمشق توقف نمود."},{"v":20,"t":"وبی درنگ، در کنایس به عیسی موعظه می‌نمود که او پسر خداست."},{"v":21,"t":"و آنانی که شنیدند تعجب نموده، گفتند: «مگر این آن کسی نیست که خوانندگان این اسم را در اورشلیم پریشان می‌نمود و در اینجا محض این آمده است تا ایشان را بند نهاده، نزد روسای کهنه برد؟»"},{"v":22,"t":"اما سولس بیشتر تقویت یافته، یهودیان ساکن دمشق رامجاب می‌نمود و مبرهن می‌ساخت که همین است مسیح."},{"v":23,"t":"اما بعد از مرور ایام چند یهودیان شورا نمودند تا او را بکشند."},{"v":24,"t":"ولی سولس ازشورای ایشان مطلع شد و شبانه‌روز به دروازه هاپاسبانی می‌نمودند تا او را بکشند."},{"v":25,"t":"پس شاگردان او را در شب در زنبیلی گذارده، از دیوارشهر پایین کردند."},{"v":26,"t":"و چون سولس به اورشلیم رسید، خواست به شاگردان ملحق شود، لیکن همه از او بترسیدندزیرا باور نکردند که از شاگردان است."},{"v":27,"t":"اما برنابااو را گرفته، به نزد رسولان برد و برای ایشان حکایت کرد که چگونه خداوند را در راه دیده وبدو تکلم کرده و چطور در دمشق به نام عیسی به دلیری موعظه می‌نمود."},{"v":28,"t":"و در اورشلیم با ایشان آمد و رفت می‌کرد و به نام خداوند عیسی به دلیری موعظه می‌نمود."},{"v":29,"t":"و با هلینستیان گفتگوو مباحثه می‌کرد. اما درصدد کشتن او برآمدند."},{"v":30,"t":"چون برادران مطلع شدند، او را به قیصریه بردند و از آنجا به طرسوس روانه نمودند."},{"v":31,"t":"آنگاه کلیسا در تمامی یهودیه و جلیل و سامره آرامی یافتند و بنا می‌شدند و در ترس خداوند وبه تسلی روح‌القدس رفتار کرده، همی افزودند."},{"v":32,"t":"اما پطرس در همه نواحی گشته، نزدمقدسین ساکن لده نیز فرود آمد."},{"v":33,"t":"و در آنجاشخصی اینیاس نام یافت که مدت هشت سال ازمرض فالج بر تخت خوابیده بود."},{"v":34,"t":"پطرس وی را گفت: «ای اینیاس، عیسی مسیح تو را شفامی دهد. برخیز و بستر خود را برچین که او درساعت برخاست.»"},{"v":35,"t":"و جمیع سکنه لده و سارون او را دیده، به سوی خداوند بازگشت کردند."},{"v":36,"t":"و در یافا، تلمیذه‌ای طابیتا نام بود که معنی آن غزال است. وی از اعمال صالحه و صدقاتی که می‌کرد، پر بود."},{"v":37,"t":"از قضا در آن ایام او بیمارشده، بمرد و او را غسل داده، در بالاخانه‌ای گذاردند."},{"v":38,"t":"و چونکه لده نزدیک به یافا بود وشاگردان شنیدند که پطرس در آنجا است، دو نفرنزد او فرستاده، خواهش کردند که «در‌آمدن نزدما درنگ نکنی.»"},{"v":39,"t":"آنگاه پطرس برخاسته، باایشان آمد و چون رسید او را بدان بالاخانه بردندو همه بیوه‌زنان گریه‌کنان حاضر بودند و پیراهنهاو جامه هایی که غزال وقتی که با ایشان بود دوخته بود، به وی نشان می‌دادند."},{"v":40,"t":"اما پطرس همه رابیرون کرده، زانو زد و دعا کرده، به سوی بدن توجه کرد و گفت: «ای طابیتا، برخیز!» که درساعت چشمان خود را باز کرد و پطرس را دیده، بنشست."},{"v":41,"t":"پس دست او را گرفته، برخیزانیدش و مقدسان و بیوه‌زنان را خوانده، او را بدیشان زنده سپرد."},{"v":42,"t":"چون این مقدمه در تمامی یافا شهرت یافت، بسیاری به خداوند ایمان آوردند."},{"v":43,"t":"و دریافا نزد دباغی شمعون نام روزی چند توقف نمود."}],"en":[{"v":1,"t":"But Saul, still breathing threats and slaughter against the disciples of the Lord, went to the high priest"},{"v":2,"t":"and asked for letters from him to the synagogues of Damascus, that if he found any who were of the Way, whether men or women, he might bring them bound to Jerusalem."},{"v":3,"t":"As he traveled, he got close to Damascus, and suddenly a light from the sky shone around him."},{"v":4,"t":"He fell on the earth, and heard a voice saying to him, “Saul, Saul, why do you persecute me?”"},{"v":5,"t":"He said, “Who are you, Lord?” The Lord said, “I am Jesus, whom you are persecuting."},{"v":6,"t":"But rise up and enter into the city, then you will be told what you must do.”"},{"v":7,"t":"The men who traveled with him stood speechless, hearing the sound, but seeing no one."},{"v":8,"t":"Saul arose from the ground, and when his eyes were opened, he saw no one. They led him by the hand and brought him into Damascus."},{"v":9,"t":"He was without sight for three days, and neither ate nor drank."},{"v":10,"t":"Now there was a certain disciple at Damascus named Ananias. The Lord said to him in a vision, “Ananias!” He said, “Behold, it’s me, Lord.”"},{"v":11,"t":"The Lord said to him, “Arise and go to the street which is called Straight, and inquire in the house of Judah for one named Saul, a man of Tarsus. For behold, he is praying,"},{"v":12,"t":"and in a vision he has seen a man named Ananias coming in and laying his hands on him, that he might receive his sight.”"},{"v":13,"t":"But Ananias answered, “Lord, I have heard from many about this man, how much evil he did to your saints at Jerusalem."},{"v":14,"t":"Here he has authority from the chief priests to bind all who call on your name.”"},{"v":15,"t":"But the Lord said to him, “Go your way, for he is my chosen vessel to bear my name before the nations and kings, and the children of Israel."},{"v":16,"t":"For I will show him how many things he must suffer for my name’s sake.”"},{"v":17,"t":"Ananias departed and entered into the house. Laying his hands on him, he said, “Brother Saul, the Lord, who appeared to you on the road by which you came, has sent me that you may receive your sight and be filled with the Holy Spirit.”"},{"v":18,"t":"Immediately something like scales fell from his eyes, and he received his sight. He arose and was baptized."},{"v":19,"t":"He took food and was strengthened. Saul stayed several days with the disciples who were at Damascus."},{"v":20,"t":"Immediately in the synagogues he proclaimed the Christ, that he is the Son of God."},{"v":21,"t":"All who heard him were amazed, and said, “Isn’t this he who in Jerusalem made havoc of those who called on this name? And he had come here intending to bring them bound before the chief priests!”"},{"v":22,"t":"But Saul increased more in strength, and confounded the Jews who lived at Damascus, proving that this is the Christ."},{"v":23,"t":"When many days were fulfilled, the Jews conspired together to kill him,"},{"v":24,"t":"but their plot became known to Saul. They watched the gates both day and night that they might kill him,"},{"v":25,"t":"but his disciples took him by night and let him down through the wall, lowering him in a basket."},{"v":26,"t":"When Saul had come to Jerusalem, he tried to join himself to the disciples; but they were all afraid of him, not believing that he was a disciple."},{"v":27,"t":"But Barnabas took him and brought him to the apostles, and declared to them how he had seen the Lord on the way, and that he had spoken to him, and how at Damascus he had preached boldly in the name of Jesus."},{"v":28,"t":"He was with them entering into Jerusalem,"},{"v":29,"t":"preaching boldly in the name of the Lord Jesus. He spoke and disputed against the Hellenists, but they were seeking to kill him."},{"v":30,"t":"When the brothers knew it, they brought him down to Caesarea and sent him off to Tarsus."},{"v":31,"t":"So the assemblies throughout all Judea, Galilee, and Samaria had peace and were built up. They were multiplied, walking in the fear of the Lord and in the comfort of the Holy Spirit."},{"v":32,"t":"As Peter went throughout all those parts, he came down also to the saints who lived at Lydda."},{"v":33,"t":"There he found a certain man named Aeneas, who had been bedridden for eight years because he was paralyzed."},{"v":34,"t":"Peter said to him, “Aeneas, Jesus Christ heals you. Get up and make your bed!” Immediately he arose."},{"v":35,"t":"All who lived at Lydda and in Sharon saw him, and they turned to the Lord."},{"v":36,"t":"Now there was at Joppa a certain disciple named Tabitha, which when translated means Dorcas. This woman was full of good works and acts of mercy which she did."},{"v":37,"t":"In those days, she became sick and died. When they had washed her, they laid her in an upper room."},{"v":38,"t":"As Lydda was near Joppa, the disciples, hearing that Peter was there, sent two men to him, imploring him not to delay in coming to them."},{"v":39,"t":"Peter got up and went with them. When he had come, they brought him into the upper room. All the widows stood by him weeping, and showing the tunics and other garments which Dorcas had made while she was with them."},{"v":40,"t":"Peter sent them all out, and knelt down and prayed. Turning to the body, he said, “Tabitha, get up!” She opened her eyes, and when she saw Peter, she sat up."},{"v":41,"t":"He gave her his hand and raised her up. Calling the saints and widows, he presented her alive."},{"v":42,"t":"This became known throughout all Joppa, and many believed in the Lord."},{"v":43,"t":"He stayed many days in Joppa with a tanner named Simon."}],"hr":[{"v":1,"t":"Savao pak, sveudilj zadahnut prijetnjom i pokoljem prema učenicima Gospodnjim, pođe k velikomu svećeniku,"},{"v":2,"t":"zaiska od njega pisma za sinagoge u Damasku, da sve koje nađe od ovoga Puta, muževe i žene, okovane dovede u Jeruzalem."},{"v":3,"t":"Kad se putujući približi Damasku, iznenada ga obasja svjetlost s neba."},{"v":4,"t":"Sruši se na zemlju i začu glas što mu govoraše: “Savle, Savle, zašto me progoniš?”"},{"v":5,"t":"On upita: “Tko si, Gospodine?” A on će: “Ja sam Isus kojega ti progoniš!"},{"v":6,"t":"Nego ustani, uđi u grad i reći će ti se što ti je činiti.”"},{"v":7,"t":"Njegovi suputnici ostadoše bez riječi: čuli su doduše glas, ali ne vidješe nikoga."},{"v":8,"t":"Savao usta sa zemlje. Otvorenih očiju nije ništa vidio pa ga povedu za ruku i uvedu u Damask."},{"v":9,"t":"Tri dana nije vidio, nije jeo ni pio."},{"v":10,"t":"U Damasku bijaše neki učenik imenom Ananija. Njemu u viđenju reče Gospodin: “Ananija!” On se odazva: “Evo me, Gospodine!”"},{"v":11,"t":"A Gospodin će mu: “Ustani, pođi u ulicu zvanu Ravna i u kući Judinoj potraži Taržanina imenom Savla. Eno, moli se;"},{"v":12,"t":"i u viđenju vidje čovjeka imenom Ananiju gdje ulazi i polaže na nj ruke da bi progledao.”"},{"v":13,"t":"Ananija odgovori: “Gospodine, od mnogih sam čuo o tom čovjeku kolika je zla tvojim svetima učinio u Jeruzalemu."},{"v":14,"t":"On ima od velikih svećenika i punomoć okovati sve koji prizivlju ime tvoje.”"},{"v":15,"t":"Gospodin mu odvrati: “Pođi jer on mi je oruđe izabrano da ponese ime moje pred narode i kraljeve i sinove Izraelove."},{"v":16,"t":"Ja ću mu uistinu pokazati koliko mu je za ime moje trpjeti.”"},{"v":17,"t":"Ananija ode, uđe u kuću, položi na nj ruke i reče: “Savle, brate! Gospodin, Isus koji ti se ukaza na putu kojim si išao, posla me da progledaš i napuniš se Duha Svetoga.”"},{"v":18,"t":"I odmah mu s očiju spade nešto kao ljuske te on progleda pa usta, krsti se"},{"v":19,"t":"i uzevši hrane, okrijepi se. Nekoliko dana provede s učenicima u Damasku."},{"v":20,"t":"te odmah stade po sinagogama propovijedati Isusa, da je on Sin Božji."},{"v":21,"t":"Koji ga god slušahu, izvan sebe govorahu: “Nije li ovo onaj koji je u Jeruzalemu istrebljivao sve koji Ime ovo prizivlju, pa i ovamo zato došao da ih okovane odvede pred velike svećenike?”"},{"v":22,"t":"Savao pak, sve silniji, zbunjivaše Židove koji prebivahu u Damasku dokazujući: “Ovo je Krist!”"},{"v":23,"t":"Pošto je minulo podosta vremena, odluče Židovi pogubiti ga,"},{"v":24,"t":"ali Savao dozna za njihov naum. Nadzirahu i vrata danju i noću da bi ga pogubili,"},{"v":25,"t":"ali ga učenici noću uzeše i preko zidina oprezno spustiše u košari."},{"v":26,"t":"Kad je Savao došao u Jeruzalem, gledao se pridružiti učenicima, ali ga se svi bojahu: nisu vjerovali da je učenik."},{"v":27,"t":"Tada ga Barnaba uze i povede k apostolima te im pripovjedi kako je Savao na putu vidio Gospodina koji mu je govorio i kako je u Damasku smjelo propovijedao u ime Isusovo."},{"v":28,"t":"Od tada se s njima slobodno kretao po Jeruzalemu i smjelo propovijedao u ime Gospodnje."},{"v":29,"t":"Govorio je i raspravljao sa Židovima grčkog jezika pa i oni snovahu pogubiti ga."},{"v":30,"t":"Saznala to braća pa ga odvedoše u Cezareju i uputiše u Tarz."},{"v":31,"t":"Crkva je po svoj Judeji, Galileji i Samariji uživala mir, izgrađivala se i napredovala u strahu Gospodnjem te rasla utjehom Svetoga Duha."},{"v":32,"t":"Jednom Petar, obilazeći posvuda, siđe i k svetima u Lidi."},{"v":33,"t":"Ondje nađe nekog čovjeka imenom Eneja, koji je osam godina ležao na postelji: bijaše uzet."},{"v":34,"t":"Reče mu Petar: “Eneja, ozdravlja te Isus Krist! Ustani i prostri sam sebi!” On umah usta."},{"v":35,"t":"Vidješe to svi žitelji Lide i Šarona te se obratiše Gospodinu."},{"v":36,"t":"U Jopi pak bijaše učenica imenom Tabita, što prevedeno znači Košuta. Bijaše ona bogata dobrim djelima i milostinjama što ih je dijelila."},{"v":37,"t":"Upravo u one dane obolje i umrije. Pošto je operu, izlože je u gornjoj sobi."},{"v":38,"t":"A kako je Lida blizu Jope, učenici čuše da je Petar ondje i poslaše k njemu dva čovjeka s molbom: “Dođi k nama, ne oklijevaj!”"},{"v":39,"t":"Petar usta i krenu s njima. Čim stiže, odvedoše ga u gornju sobu. Okružiše ga sve udovice te mu plačući pokazivahu haljine i odijela što ih je Košuta izrađivala dok je još bila s njima."},{"v":40,"t":"Petar sve istjera van, kleknu, pomoli se pa se okrenu prema tijelu i reče: “Tabita, ustani!” Ona otvori oči, pogleda Petra i sjede."},{"v":41,"t":"On joj pruži ruku i pridiže je. Onda pozove svete i udovice pa im je pokaza živu."},{"v":42,"t":"Dozna se za to po svoj Jopi te mnogi povjerovaše u Gospodina."},{"v":43,"t":"Petar osta neko vrijeme u Jopi u nekog Šimuna kožara."}]},"10":{"fa":[{"v":1,"t":"و در قیصریه مردی کرنیلیوس نام بود، یوزباشی فوجی که به ایطالیانی مشهوراست."},{"v":2,"t":"و او با تمامی اهل بیتش متقی و خداترس بود که صدقه بسیار به قوم می‌داد و پیوسته نزدخدا دعا می‌کرد."},{"v":3,"t":"روزی نزدیک ساعت نهم، فرشته خدا را در عالم رویا آشکارا دید که نزد اوآمده، گفت: «ای کرنیلیوس!»"},{"v":4,"t":"آنگاه او بر وی نیک نگریسته و ترسان گشته، گفت: «چیست‌ای خداوند؟» به وی گفت: «دعاها و صدقات تو بجهت یادگاری به نزد خدا برآمد."},{"v":5,"t":"اکنون کسانی به یافا بفرست و شمعون ملقب به پطرس را طلب کن"},{"v":6,"t":"که نزد دباغی شمعون نام که خانه‌اش به کناره دریا است، مهمان است. او به تو خواهد گفت که تو را چه باید کرد."},{"v":7,"t":"و چون فرشته‌ای که به وی سخن می‌گفت غایب شد، دو نفر از نوکران خود ویک سپاهی متقی از ملازمان خاص خویشتن راخوانده،"},{"v":8,"t":"تمامی ماجرا را بدیشان باز‌گفته، ایشان را به یافا فرستاد."},{"v":9,"t":"روز دیگر چون از سفر نزدیک به شهرمی رسیدند، قریب به ساعت ششم، پطرس به بام خانه برآمد تا دعا کند."},{"v":10,"t":"و واقع شد که گرسنه شده، خواست چیزی بخورد. اما چون برای اوحاضر می‌کردند، بی‌خودی او را رخ نمود."},{"v":11,"t":"پس آسمان را گشاده دید و ظرفی را چون چادری بزرگ به چهار گوشه بسته، به سوی زمین آویخته بر او نازل می‌شود،"},{"v":12,"t":"که در آن هر قسمی ازدواب و وحوش و حشرات زمین و مرغان هوابودند."},{"v":13,"t":"و خطابی به وی رسید که «ای پطرس برخاسته، ذبح کن و بخور.»"},{"v":14,"t":"پطرس گفت: «حاشا خداوندا زیرا چیزی ناپاک یا حرام هرگزنخورده‌ام.»"},{"v":15,"t":"بار دیگر خطاب به وی رسید که «آنچه خدا پاک کرده است، تو حرام مخوان.»"},{"v":16,"t":"واین سه مرتبه واقع شد که در ساعت آن ظرف به آسمان بالا برده شد."},{"v":17,"t":"و چون پطرس در خود بسیار متحیر بود که این‌رویایی که دید چه باشد، ناگاه فرستادگان کرنیلیوس خانه شمعون را تفحص کرده، بر درگاه رسیدند،"},{"v":18,"t":"و ندا کرده، می‌پرسیدند که «شمعون معروف به پطرس در اینجا منزل دارد؟»"},{"v":19,"t":"وچون پطرس در رویا تفکر می‌کرد، روح وی راگفت: «اینک سه مرد تو را می‌طلبند."},{"v":20,"t":"پس برخاسته، پایین شو و همراه ایشان برو و هیچ شک مبر زیرا که من ایشان را فرستادم.»"},{"v":21,"t":"پس پطرس نزد آنانی که کرنیلیوس نزد وی فرستاده بود، پایین آمده، گفت: «اینک منم آن کس که می‌طلبید. سبب آمدن شما چیست؟»"},{"v":22,"t":"گفتند: «کرنیلیوس یوزباشی، مرد صالح و خداترس و نزد تمامی طایفه یهود نیکنام، از فرشته مقدس الهام یافت که تو را به خانه خود بطلبد و سخنان از تو بشنود.»"},{"v":23,"t":"پس ایشان را به خانه برده، مهمانی نمود. وفردای آن روز پطرس برخاسته، همراه ایشان روانه شد و چند نفر از برادران یافا همراه او رفتند."},{"v":24,"t":"روز دیگر وارد قیصریه شدند و کرنیلیوس خویشان و دوستان خاص خود را خوانده، انتظارایشان می‌کشید."},{"v":25,"t":"چون پطرس داخل شد، کرنیلیوس او را استقبال کرده، بر پایهایش افتاده، پرستش کرد."},{"v":26,"t":"اما پطرس او را برخیزانیده، گفت: «برخیز، من خود نیز انسان هستم.»"},{"v":27,"t":"و با اوگفتگوکنان به خانه درآمده، جمعی کثیر یافت."},{"v":28,"t":"پس بدیشان گفت: «شما مطلع هستید که مردیهودی را با شخص اجنبی معاشرت کردن یا نزداو آمدن حرام است. لیکن خدا مرا تعلیم داد که هیچ‌کس را حرام یا نجس نخوانم."},{"v":29,"t":"از این جهت به مجرد خواهش شما بی‌تامل آمدم و الحال می‌پرسم که از برای چه مرا خواسته‌اید.»"},{"v":30,"t":"کرنیلیوس گفت: «چهار روز قبل از این، تااین ساعت روزه‌دار می‌بودم؛ و در ساعت نهم درخانه خود دعا می‌کردم که ناگاه شخصی با لباس نورانی پیش من بایستاد"},{"v":31,"t":"و گفت: “ای کرنیلیوس دعای تو مستجاب شد و صدقات تو در حضورخدا یادآور گردید."},{"v":32,"t":"پس به یافا بفرست و شمعون معروف به پطرس را طلب نما که در خانه شمعون دباغ به کناره دریا مهمان است. او چون بیاید با تو سخن خواهد راند.”"},{"v":33,"t":"پس بی‌تامل نزدتو فرستادم و تو نیکو کردی که آمدی. الحال همه در حضور خدا حاضریم تا آنچه خدا به توفرموده است بشنویم.»"},{"v":34,"t":"پطرس زبان را گشوده، گفت: «فی الحقیقت یافته‌ام که خدا را نظر به ظاهر نیست،"},{"v":35,"t":"بلکه ازهر امتی، هر‌که از او ترسد و عمل نیکو کند، نزداو مقبول گردد."},{"v":36,"t":"کلامی را که نزد بنی‌اسرائیل فرستاد، چونکه به وساطت عیسی مسیح که خداوند همه است به سلامتی بشارت می‌داد،"},{"v":37,"t":"آن سخن را شما می‌دانید که شروع آن از جلیل بود و در تمامی یهودیه منتشر شد، بعد از آن تعمیدی که یحیی بدان موعظه می‌نمود،"},{"v":38,"t":"یعنی عیسی ناصری را که خدا او را چگونه به روح‌القدس و قوت مسح نمود که او سیر کرده، اعمال نیکو به‌جا می‌آورد و همه مقهورین ابلیس را شفا می‌بخشید زیرا خدا با وی می‌بود."},{"v":39,"t":"و ماشاهد هستیم بر جمیع کارهایی که او در مرزوبوم یهود و در اورشلیم کرد که او را نیز بر صلیب کشیده، کشتند."},{"v":40,"t":"همان کس را خدا در روز سوم برخیزانیده، ظاهر ساخت."},{"v":41,"t":"لیکن نه بر تمامی قوم بلکه بر شهودی که خدا پیش برگزیده بود، یعنی مایانی که بعد از برخاستن او از مردگان با اوخورده و آشامیده‌ایم."},{"v":42,"t":"و ما را مامور فرمود که به قوم موعظه و شهادت دهیم بدین که خدا او رامقرر فرمود تا داور زندگان و مردگان باشد."},{"v":43,"t":"وجمیع انبیا بر او شهادت می‌دهند که هر‌که به وی ایمان آورد، به اسم او آمرزش گناهان را خواهد یافت.»"},{"v":44,"t":"این سخنان هنوز بر زبان پطرس بود که روح‌القدس بر همه آنانی که کلام را شنیدند، نازل شد."},{"v":45,"t":"و مومنان از اهل ختنه که همراه پطرس آمده بودند، در حیرت افتادند از آنکه بر امت هانیز عطای روح‌القدس افاضه شد،"},{"v":46,"t":"زیرا که ایشان را شنیدند که به زبانها متکلم شده، خدا راتمجید می‌کردند."},{"v":47,"t":"آنگاه پطرس گفت: «آیاکسی می‌تواند آب را منع کند، برای تعمید دادن اینانی که روح‌القدس را چون ما نیز یافته‌اند.»"},{"v":48,"t":"پس فرمود تا ایشان را به نام عیسی مسیح تعمید دهند. آنگاه از او خواهش نمودند که روزی چند توقف نماید."}],"en":[{"v":1,"t":"Now there was a certain man in Caesarea, Cornelius by name, a centurion of what was called the Italian Regiment,"},{"v":2,"t":"a devout man, and one who feared God with all his house, who gave gifts for the needy generously to the people, and always prayed to God."},{"v":3,"t":"At about the ninth hour of the day, he clearly saw in a vision an angel of God coming to him and saying to him, “Cornelius!”"},{"v":4,"t":"He, fastening his eyes on him and being frightened, said, “What is it, Lord?” He said to him, “Your prayers and your gifts to the needy have gone up for a memorial before God."},{"v":5,"t":"Now send men to Joppa, and get Simon, who is also called Peter."},{"v":6,"t":"He is staying with a tanner named Simon, whose house is by the seaside."},{"v":7,"t":"When the angel who spoke to him had departed, Cornelius called two of his household servants and a devout soldier of those who waited on him continually."},{"v":8,"t":"Having explained everything to them, he sent them to Joppa."},{"v":9,"t":"Now on the next day as they were on their journey and got close to the city, Peter went up on the housetop to pray at about noon."},{"v":10,"t":"He became hungry and desired to eat, but while they were preparing, he fell into a trance."},{"v":11,"t":"He saw heaven opened and a certain container descending to him, like a great sheet let down by four corners on the earth,"},{"v":12,"t":"in which were all kinds of four-footed animals of the earth, wild animals, reptiles, and birds of the sky."},{"v":13,"t":"A voice came to him, “Rise, Peter, kill and eat!”"},{"v":14,"t":"But Peter said, “Not so, Lord; for I have never eaten anything that is common or unclean.”"},{"v":15,"t":"A voice came to him again the second time, “What God has cleansed, you must not call unclean.”"},{"v":16,"t":"This was done three times, and immediately the thing was received up into heaven."},{"v":17,"t":"Now while Peter was very perplexed in himself what the vision which he had seen might mean, behold, the men who were sent by Cornelius, having made inquiry for Simon’s house, stood before the gate,"},{"v":18,"t":"and called and asked whether Simon, who was also called Peter, was lodging there."},{"v":19,"t":"While Peter was pondering the vision, the Spirit said to him, “Behold, three men seek you."},{"v":20,"t":"But arise, get down, and go with them, doubting nothing; for I have sent them.”"},{"v":21,"t":"Peter went down to the men, and said, “Behold, I am he whom you seek. Why have you come?”"},{"v":22,"t":"They said, “Cornelius, a centurion, a righteous man and one who fears God, and well spoken of by all the nation of the Jews, was directed by a holy angel to invite you to his house, and to listen to what you say.”"},{"v":23,"t":"So he called them in and provided a place to stay. On the next day Peter arose and went out with them, and some of the brothers from Joppa accompanied him."},{"v":24,"t":"On the next day they entered into Caesarea. Cornelius was waiting for them, having called together his relatives and his near friends."},{"v":25,"t":"When Peter entered, Cornelius met him, fell down at his feet, and worshiped him."},{"v":26,"t":"But Peter raised him up, saying, “Stand up! I myself am also a man.”"},{"v":27,"t":"As he talked with him, he went in and found many gathered together."},{"v":28,"t":"He said to them, “You yourselves know how it is an unlawful thing for a man who is a Jew to join himself or come to one of another nation, but God has shown me that I shouldn’t call any man unholy or unclean."},{"v":29,"t":"Therefore I also came without complaint when I was sent for. I ask therefore, why did you send for me?”"},{"v":30,"t":"Cornelius said, “Four days ago, I was fasting until this hour; and at the ninth hour, I prayed in my house, and behold, a man stood before me in bright clothing"},{"v":31,"t":"and said, ‘Cornelius, your prayer is heard, and your gifts to the needy are remembered in the sight of God."},{"v":32,"t":"Send therefore to Joppa and summon Simon, who is also called Peter. He is staying in the house of a tanner named Simon, by the seaside. When he comes, he will speak to you.’"},{"v":33,"t":"Therefore I sent to you at once, and it was good of you to come. Now therefore we are all here present in the sight of God to hear all things that have been commanded you by God.”"},{"v":34,"t":"Peter opened his mouth and said, “Truly I perceive that God doesn’t show favoritism;"},{"v":35,"t":"but in every nation he who fears him and works righteousness is acceptable to him."},{"v":36,"t":"The word which he sent to the children of Israel, preaching good news of peace by Jesus Christ—he is Lord of all—"},{"v":37,"t":"you yourselves know what happened, which was proclaimed throughout all Judea, beginning from Galilee, after the baptism which John preached;"},{"v":38,"t":"how God anointed Jesus of Nazareth with the Holy Spirit and with power, who went about doing good and healing all who were oppressed by the devil, for God was with him."},{"v":39,"t":"We are witnesses of everything he did both in the country of the Jews and in Jerusalem; whom they also killed, hanging him on a tree."},{"v":40,"t":"God raised him up the third day and gave him to be revealed,"},{"v":41,"t":"not to all the people, but to witnesses who were chosen before by God, to us, who ate and drank with him after he rose from the dead."},{"v":42,"t":"He commanded us to preach to the people and to testify that this is he who is appointed by God as the Judge of the living and the dead."},{"v":43,"t":"All the prophets testify about him, that through his name everyone who believes in him will receive remission of sins.”"},{"v":44,"t":"While Peter was still speaking these words, the Holy Spirit fell on all those who heard the word."},{"v":45,"t":"They of the circumcision who believed were amazed, as many as came with Peter, because the gift of the Holy Spirit was also poured out on the Gentiles."},{"v":46,"t":"For they heard them speaking in other languages and magnifying God. Then Peter answered,"},{"v":47,"t":"“Can anyone forbid these people from being baptized with water? They have received the Holy Spirit just like us.”"},{"v":48,"t":"He commanded them to be baptized in the name of Jesus Christ. Then they asked him to stay some days."}],"hr":[{"v":1,"t":"U Cezareji bijaše neki čovjek imenom Kornelije, satnik takozvane italske čete,"},{"v":2,"t":"pobožan i bogobojazan sa svim svojim domom. Dijelio je mnoge milostinje narodu i bez prestanka se molio Bogu."},{"v":3,"t":"U viđenju negdje oko devete ure dana ugleda on jasno anđela Božjega gdje dolazi k njemu i veli mu: “Kornelije!”"},{"v":4,"t":"Zagleda se u nj pa mu prestrašen reče: “Što je, Gospodine?” A on njemu: “Molitve su tvoje i milostinje uzišle kao žrtva podsjetnica pred Boga."},{"v":5,"t":"Zato sada pošalji ljude u Jopu i dozovi Šimuna koji se zove Petar."},{"v":6,"t":"On je gost u nekog Šimuna kožara čija je kuća uz more.”"},{"v":7,"t":"Čim ode anđeo koji mu je govorio, pozove on dvojicu slugu i jednoga pobožna, privržena vojnika,"},{"v":8,"t":"sve im ispripovjedi i posla ih u Jopu."},{"v":9,"t":"Sutradan, dok su oni putovali i približavali se gradu, oko šeste ure uziđe Petar na krov moliti."},{"v":10,"t":"Ogladnje i zaželje se jela. Dok mu pripremahu, pade on u zanos."},{"v":11,"t":"Gleda on nebo rastvoreno i posudu neku poput velika platna: uleknuta s četiri okrajka, silazi na zemlju."},{"v":12,"t":"U njoj bijahu svakovrsni četveronošci, gmazovi zemaljski i ptice nebeske."},{"v":13,"t":"I glas će mu neki: “Ustaj, Petre! Kolji i jedi!”"},{"v":14,"t":"Petar odvrati: “Nipošto, Gospodine! Ta nikad još ne okusih ništa okaljano i nečisto”."},{"v":15,"t":"A glas će mu opet, po drugi put: “Što Bog očisti, ti ne zovi okaljanim!”"},{"v":16,"t":"To se ponovi do triput, a onda je posuda ponesena na nebo."},{"v":17,"t":"Dok se Petar dvoumio što bi imalo značiti viđenje koje vidje, eto ljudi koje je poslao Kornelije: pošto se raspitaše za Šimunovu kuću, pojave se na vratima,"},{"v":18,"t":"zovnu te upitaju je li ondje ugošćen neki Šimun, nazvan Petar."},{"v":19,"t":"Dok je Petar sveudilj razmišljao o viđenju, reče mu Duh: “Evo, neka te trojica traže."},{"v":20,"t":"De ustani, siđi i pođi s njima ne skanjujući se jer ja sam ih poslao.”"},{"v":21,"t":"Petar siđe k ljudima i reče: “Evo me! Ja sam onaj kojega tražite! Zbog čega ste došli?”"},{"v":22,"t":"Oni odgovore: “Satnik Kornelije, muž pravedan i bogobojazan, za kojega svjedoči sav narod židovski, primi od svetog anđela naputak da te dozove u dom svoj i čuje od tebe riječi.”"},{"v":23,"t":"Tada ih Petar pozva unutra i ugosti. Sutradan usta i krenu s njima; pratila ga neka braća iz Jope."},{"v":24,"t":"Drugi dan stiže u Cezareju. Kornelije ih je čekao sazvavši rodbinu i prisne prijatelje."},{"v":25,"t":"Kad je Petar ulazio, pohrli mu Kornelije u susret, padne mu k nogama i pokloni se."},{"v":26,"t":"Petar ga pridigne govoreći: “Ustani! I ja sam čovjek.”"},{"v":27,"t":"I razgovarajući s njime, uđe i nađe sabrane mnoge"},{"v":28,"t":"te im reče: “Vi znate kako je Židovu zabranjeno družiti se sa strancem ili k njemu ulaziti, ali meni Bog pokaza da nikoga ne zovem okaljanim ili nečistim."},{"v":29,"t":"Stoga, pozvan, i dođoh bez pogovora. Da čujemo dakle zbog čega me pozvaste!”"},{"v":30,"t":"Kornelije reče: “Prije četiri dana baš u ovo doba, o devetoj uri, molio sam se u kući kad gle: čovjek neki u sjajnoj odjeći stane preda me"},{"v":31,"t":"i reče: 'Kornelije, uslišana ti je molitva i milostinje su tvoje spomenute pred Bogom!"},{"v":32,"t":"Pošalji dakle u Jopu i dozovi Šimuna koji se zove Petar. On je gost u kući Šimuna kožara uz more.'"},{"v":33,"t":"Odmah sam dakle poslao k tebi, a ti si dobro učinio što si došao. Evo nas dakle sviju pred Bogom da čujemo sve što ti zapovjedi Gospodin!”"},{"v":34,"t":"Petar tada prozbori i reče: “Sad uistinu shvaćam da Bog nije pristran,"},{"v":35,"t":"nego - u svakom je narodu njemu mio onaj koji ga se boji i čini pravdu."},{"v":36,"t":"Riječ posla sinovima Izraelovim navješćujući im evanđelje: mir po Isusu Kristu; on je Gospodar sviju."},{"v":37,"t":"Vi znate što se događalo po svoj Judeji, počevši od Galileje, nakon krštenja koje je propovijedao Ivan:"},{"v":38,"t":"kako Isusa iz Nazareta Bog pomaza Duhom Svetim i snagom, njega koji je, jer Bog bijaše s njime, prošao zemljom čineći dobro i ozdravljajući sve kojima bijaše ovladao đavao.”"},{"v":39,"t":"“Mi smo svjedoci svega što on učini u zemlji judejskoj i Jeruzalemu. I njega smakoše, objesivši ga na drvo!"},{"v":40,"t":"Bog ga uskrisi treći dan i dade mu da se očituje -"},{"v":41,"t":"ne svemu narodu, nego svjedocima od Boga predodređenima - nama koji smo s njime zajedno jeli i pili pošto uskrsnu od mrtvih.”"},{"v":42,"t":"“On nam i naloži propovijedati narodu i svjedočiti: Ovo je onaj kojega Bog postavi sucem živih i mrtvih!”"},{"v":43,"t":"“Za nj svjedoče svi proroci: da tko god u nj vjeruje, po imenu njegovu prima oproštenje grijeha.”"},{"v":44,"t":"Dok je Petar još govorio te riječi, siđe Duh Sveti na sve koji su slušali tu besjedu."},{"v":45,"t":"A vjernici iz obrezanja, koji dođoše zajedno s Petrom, začudiše se što se i na pogane izlio dar Duha Svetoga."},{"v":46,"t":"Jer čuli su ih govoriti drugim jezicima i veličati Boga. Tada Petar reče:"},{"v":47,"t":"“Može li tko uskratiti vodu da se ne krste ovi koji su primili Duha Svetoga kao i mi?”"},{"v":48,"t":"I zapovjedi da se krste u ime Isusa Krista. Tada ga zamole da ostane ondje nekoliko dana."}]},"11":{"fa":[{"v":1,"t":"پس رسولان و برادرانی که در یهودیه بودند، شنیدند که امت‌ها نیز کلام خدارا پذیرفته‌اند."},{"v":2,"t":"و چون پطرس به اورشلیم آمد، اهل ختنه با وی معارضه کرده،"},{"v":3,"t":"گفتند که «بامردم نامختون برآمده، با ایشان غذا خوردی!»"},{"v":4,"t":"پطرس از اول مفصلا بدیشان بیان کرده، گفت:"},{"v":5,"t":"«من در شهر یافا دعا می‌کردم که ناگاه درعالم رویا ظرفی را دیدم که نازل می‌شود مثل چادری بزرگ به چهار گوشه از آسمان آویخته که بر من می‌رسد."},{"v":6,"t":"چون بر آن نیک نگریسته، تامل کردم، دواب زمین و وحوش و حشرات و مرغان هوا را دیدم."},{"v":7,"t":"و آوازی را شنیدم که به من می‌گوید: “ای پطرس برخاسته، ذبح کن و بخور.”"},{"v":8,"t":"گفتم: “حاشا خداوندا، زیرا هرگز چیزی حرام یا ناپاک به دهانم نرفته است.”"},{"v":9,"t":"بار دیگر خطاب از آسمان در‌رسید که “آنچه خدا پاک نموده، توحرام مخوان.”"},{"v":10,"t":"این سه کرت واقع شد که همه باز به سوی آسمان بالا برده شد."},{"v":11,"t":"و اینک در همان ساعت سه مرد از قیصریه نزد من فرستاده شده، به خانه‌ای که در آن بودم، رسیدند."},{"v":12,"t":"و روح مرا گفت که «با ایشان بدون شک برو.» و این شش برادر نیز همراه من آمدند تابه خانه آن شخص داخل شدیم."},{"v":13,"t":"و ما راآگاهانید که چطور فرشته‌ای را در خانه خود دیدکه ایستاده به وی گفت “کسان به یافا بفرست وشمعون معروف به پطرس را بطلب"},{"v":14,"t":"که با توسخنانی خواهد گفت که بدانها تو و تمامی اهل خانه تو نجات خواهید یافت.”"},{"v":15,"t":"و چون شروع به سخن‌گفتن می‌کردم، روح‌القدس بر ایشان نازل شد، همچنانکه نخست بر ما."},{"v":16,"t":"آنگاه بخاطرآوردم سخن خداوند را که گفت: “یحیی به آب تعمید داد، لیکن شما به روح‌القدس تعمیدخواهید یافت.”"},{"v":17,"t":"پس چون خدا همان عطا رابدیشان بخشید، چنانکه به ما محض ایمان آوردن به عیسی مسیح خداوند، پس من که باشم که بتوانم خدا را ممانعت نمایم؟»"},{"v":18,"t":"چون این را شنیدند، ساکت شدند و خدا را تمجیدکنان گفتند: «فی الحقیقت، خدا به امت‌ها نیز توبه حیات‌بخش را عطا کرده است!»"},{"v":19,"t":"و آنانی که به‌سبب اذیتی که در مقدمه استیفان برپا شد متفرق شدند، تا فینیقیا و قپرس وانطاکیه می‌گشتند و به هیچ‌کس به غیر از یهود وبس کلام را نگفتند."},{"v":20,"t":"لیکن بعضی از ایشان که از اهل قپرس و قیروان بودند، چون به انطاکیه رسیدند با یونانیان نیز تکلم کردند و به خداوندعیسی بشارت می‌دادند،"},{"v":21,"t":"و دست خداوند باایشان می‌بود و جمعی کثیر ایمان آورده، به سوی خداوند بازگشت کردند."},{"v":22,"t":"اما چون خبر ایشان به سمع کلیسای اورشلیم رسید، برنابا را به انطاکیه فرستادند"},{"v":23,"t":"و چون رسید و فیض خدا را دید، شادخاطر شده، همه را نصیحت نمود که ازتصمیم قلب به خداوند بپیوندند."},{"v":24,"t":"زیرا که مردی صالح و پر از روح‌القدس و ایمان بود وگروهی بسیار به خداوند ایمان آوردند."},{"v":25,"t":"و برنابابه طرسوس برای طلب سولس رفت و چون او رایافت به انطاکیه آورد."},{"v":26,"t":"و ایشان سالی تمام درکلیسا جمع می‌شدند و خلقی بسیار را تعلیم می‌دادند و شاگردان نخست در انطاکیه به مسیحی مسمی شدند."},{"v":27,"t":"و در آن ایام انبیایی چند از اورشلیم به انطاکیه آمدند"},{"v":28,"t":"که یکی از ایشان اغابوس نام برخاسته، به روح اشاره کرد که قحطی شدید درتمامی ربع مسکون خواهد شد و آن در ایام کلودیوس قیصر پدید آمد."},{"v":29,"t":"و شاگردان مصمم آن شدند که هر یک برحسب مقدور خود، اعانتی برای برادران ساکن یهودیه بفرستند."},{"v":30,"t":"پس چنین کردند و آن را به‌دست برنابا و سولس نزد کشیشان روانه نمودند."}],"en":[{"v":1,"t":"Now the apostles and the brothers who were in Judea heard that the Gentiles had also received the word of God."},{"v":2,"t":"When Peter had come up to Jerusalem, those who were of the circumcision contended with him,"},{"v":3,"t":"saying, “You went in to uncircumcised men and ate with them!”"},{"v":4,"t":"But Peter began, and explained to them in order, saying,"},{"v":5,"t":"“I was in the city of Joppa praying, and in a trance I saw a vision: a certain container descending, like it was a great sheet let down from heaven by four corners. It came as far as me."},{"v":6,"t":"When I had looked intently at it, I considered, and saw the four-footed animals of the earth, wild animals, creeping things, and birds of the sky."},{"v":7,"t":"I also heard a voice saying to me, ‘Rise, Peter, kill and eat!’"},{"v":8,"t":"But I said, ‘Not so, Lord, for nothing unholy or unclean has ever entered into my mouth.’"},{"v":9,"t":"But a voice answered me the second time out of heaven, ‘What God has cleansed, don’t you call unclean.’"},{"v":10,"t":"This was done three times, and all were drawn up again into heaven."},{"v":11,"t":"Behold, immediately three men stood before the house where I was, having been sent from Caesarea to me."},{"v":12,"t":"The Spirit told me to go with them without discriminating. These six brothers also accompanied me, and we entered into the man’s house."},{"v":13,"t":"He told us how he had seen the angel standing in his house and saying to him, ‘Send to Joppa and get Simon, who is called Peter,"},{"v":14,"t":"who will speak to you words by which you will be saved, you and all your house.’"},{"v":15,"t":"As I began to speak, the Holy Spirit fell on them, even as on us at the beginning."},{"v":16,"t":"I remembered the word of the Lord, how he said, ‘John indeed baptized in water, but you will be baptized in the Holy Spirit.’"},{"v":17,"t":"If then God gave to them the same gift as us when we believed in the Lord Jesus Christ, who was I, that I could withstand God?”"},{"v":18,"t":"When they heard these things, they held their peace and glorified God, saying, “Then God has also granted to the Gentiles repentance to life!”"},{"v":19,"t":"They therefore who were scattered abroad by the oppression that arose about Stephen traveled as far as Phoenicia, Cyprus, and Antioch, speaking the word to no one except to Jews only."},{"v":20,"t":"But there were some of them, men of Cyprus and Cyrene, who, when they had come to Antioch, spoke to the Hellenists, preaching the Lord Jesus."},{"v":21,"t":"The hand of the Lord was with them, and a great number believed and turned to the Lord."},{"v":22,"t":"The report concerning them came to the ears of the assembly which was in Jerusalem. They sent out Barnabas to go as far as Antioch,"},{"v":23,"t":"who, when he had come, and had seen the grace of God, was glad. He exhorted them all, that with purpose of heart they should remain near to the Lord."},{"v":24,"t":"For he was a good man, and full of the Holy Spirit and of faith, and many people were added to the Lord."},{"v":25,"t":"Barnabas went out to Tarsus to look for Saul."},{"v":26,"t":"When he had found him, he brought him to Antioch. For a whole year they were gathered together with the assembly, and taught many people. The disciples were first called Christians in Antioch."},{"v":27,"t":"Now in these days, prophets came down from Jerusalem to Antioch."},{"v":28,"t":"One of them named Agabus stood up and indicated by the Spirit that there should be a great famine all over the world, which also happened in the days of Claudius."},{"v":29,"t":"As any of the disciples had plenty, each determined to send relief to the brothers who lived in Judea;"},{"v":30,"t":"which they also did, sending it to the elders by the hands of Barnabas and Saul."}],"hr":[{"v":1,"t":"Dočuli apostoli i braća po Judeji da i pogani primiše riječ Božju"},{"v":2,"t":"pa kad Petar uziđe u Jeruzalem, uzeše mu obrezanici prigovarati:"},{"v":3,"t":"“Ušao si, dobacivahu, k ljudima neobrezanima i jeo s njima!”"},{"v":4,"t":"Onda započe Petar te im izloži sve po redu:"},{"v":5,"t":"“Molio sam se, reče, u Jopi kadli u zanosu ugledam viđenje: posudu neku poput velika platna, uleknuta s četiri okrajka, gdje silazi s neba i dolazi do mene."},{"v":6,"t":"Zagledah se, promotrih je i vidjeh četvoronošce zemaljske, zvijeri i gmazove te ptice nebeske."},{"v":7,"t":"Začuh i glas koji mi govoraše: 'Ustaj, Petre! Kolji i jedi!'"},{"v":8,"t":"Ja odvratih: 'Nipošto, Gospodine! Ta nikad mi još ništa okaljano ili nečisto ne uđe u usta.'"},{"v":9,"t":"A glas će s neba po drugi put: 'Što Bog očisti, ti ne zovi nečistim.'"},{"v":10,"t":"To se ponovi do triput, a onda se sve opet povuče na nebo.”"},{"v":11,"t":"“I odmah se, evo, pred kućom u kojoj bijah pojaviše tri čovjeka poslana iz Cezareje k meni."},{"v":12,"t":"A Duh mi reče da pođem s njima ništa ne premišljajući. Sa mnom pođoše i ova šestorica braće te uđosmo u kuću tog čovjeka."},{"v":13,"t":"On nam pripovjedi kako je u svojoj kući vidio anđela koji je stao preda nj i rekao: 'Pošalji u Jopu i dozovi Šimuna nazvanog Petar;"},{"v":14,"t":"on će ti navijestiti riječi po kojima ćeš se spasiti ti i sav dom tvoj.'”"},{"v":15,"t":"“I kad počeh govoriti, siđe na njih Duh Sveti kao ono na nas u početku."},{"v":16,"t":"Sjetih se tada riječi Gospodnje: 'Ivan je, govoraše on, krstio vodom, a vi ćete biti kršteni Duhom Svetim.'"},{"v":17,"t":"Ako im je dakle Bog dao isti dar kao i nama koji povjerovasmo u Gospodina Isusa Krista, tko sam ja da bih se smio oprijeti Bogu?”"},{"v":18,"t":"Kad su to čuli, umiriše se te stadoše slaviti Boga govoreći: “Dakle i poganima Bog dade obraćenje na život!”"},{"v":19,"t":"Oni dakle što ih rasprši nevolja nastala u povodu Stjepana dopriješe do Fenicije, Cipra i Antiohije, nikomu ne propovijedajući Riječi doli samo Židovima."},{"v":20,"t":"Neki su od njih bili Ciprani i Cirenci. Kad stigoše u Antiohiju, propovijedahu i Grcima navješćujući evanđelje: Gospodina, Isusa."},{"v":21,"t":"Ruka Gospodnja bijaše s njima te velik broj ljudi povjerova i obrati se Gospodinu."},{"v":22,"t":"Vijest o tome doprije do Crkve u Jeruzalemu pa poslaše Barnabu u Antiohiju."},{"v":23,"t":"Kad on stiže i vidje milost Božju, obradova se te potaknu sve da u odlučnosti srca ostanu uz Gospodina."},{"v":24,"t":"Ta bijaše to muž čestit, pun Duha Svetoga i vjere. Znatno se mnoštvo prikloni Gospodinu."},{"v":25,"t":"Barnaba se zatim zaputi u Tarz potražiti Savla."},{"v":26,"t":"Kad ga nađe, odvede ga u Antiohiju. Punu su se godinu dana sastajali u toj Crkvi i poučavali poveće mnoštvo te se u Antiohiji učenici najprije prozvaše kršćanima."},{"v":27,"t":"U one dane dođoše u Antiohiju neki proroci iz Jeruzalema."},{"v":28,"t":"Jedan od njih, imenom Agab, usta i po Duhu pretkaza da će uskoro nastati velika glad po svem svijetu. Ona i nasta za Klaudija."},{"v":29,"t":"Stoga će svatko od učenika, odlučiše, koliko smogne poslati da se posluži braći u Judeji."},{"v":30,"t":"To i učiniše te poslaše starješinama po Barnabi i Savlu."}]},"12":{"fa":[{"v":1,"t":"و در آن زمان هیرودیس پادشاه، دست تطاول بر بعضی از کلیسا دراز کرد"},{"v":2,"t":"ویعقوب برادر یوحنا را به شمشیر کشت."},{"v":3,"t":"و چون دید که یهود را پسند افتاد، بر آن افزوده، پطرس رانیز گرفتار کرد و ایام فطیر بود."},{"v":4,"t":"پس او را گرفته، در زندان انداخت و به چهار دسته رباعی سپاهیان سپرد که او را نگاهبانی کنند و اراده داشت که بعداز فصح او را برای قوم بیرون آورد."},{"v":5,"t":"پس پطرس را در زندان نگاه می‌داشتند."},{"v":6,"t":"و در شبی که هیرودیس قصد بیرون آوردن وی داشت، پطرس به دو زنجیر بسته، درمیان دو سپاهی خفته بود و کشیکچیان نزد درزندان را نگاهبانی می‌کردند."},{"v":7,"t":"ناگاه فرشته خداوند نزد وی حاضر شد و روشنی در آن خانه درخشید. پس به پهلوی پطرس زده، او را بیدارنمود و گفت: «بزودی برخیز.» که در ساعت زنجیرها از دستش فرو ریخت."},{"v":8,"t":"و فرشته وی راگفت: «کمر خود را ببند و نعلین برپا کن.» پس چنین کرد و به وی گفت: «ردای خود را بپوش و ازعقب من بیا.»"},{"v":9,"t":"پس بیرون شده، از عقب او روانه گردید و ندانست که آنچه از فرشته روی نمودحقیقی است بلکه گمان برد که خواب می‌بیند."},{"v":10,"t":"پس از قراولان اول و دوم گذشته، به دروازه آهنی که به سوی شهر می‌رود رسیدند و آن خودبخود پیش روی ایشان باز شد؛ و از آن بیرون رفته، تا آخر یک کوچه برفتند که در ساعت فرشته از او غایب شد."},{"v":11,"t":"آنگاه پطرس به خودآمده گفت: «اکنون به تحقیق دانستم که خداوندفرشته خود را فرستاده، مرا از دست هیرودیس واز تمامی انتظار قوم یهود رهانید.»"},{"v":12,"t":"چون این را دریافت، به خانه مریم مادریوحنای ملقب به مرقس آمد و در آنجا بسیاری جمع شده، دعا می‌کردند."},{"v":13,"t":"چون او در خانه راکوبید، کنیزی رودا نام آمد تا بفهمد."},{"v":14,"t":"چون آوازپطرس را شناخت، از خوشی در را باز نکرده، به اندرون شتافته، خبر داد که «پطرس به درگاه ایستاده است.»"},{"v":15,"t":"وی را گفتند: «دیوانه‌ای.» وچون تاکید کرد که چنین است، گفتند که فرشته اوباشد.»"},{"v":16,"t":"اما پطرس پیوسته در را می‌کوبید. پس در را گشوده، او را دیدند و در حیرت افتادند."},{"v":17,"t":"اما او به‌دست خود به سوی ایشان اشاره کردکه خاموش باشند و بیان نمود که چگونه خدا او رااز زندان خلاصی داد و گفت: «یعقوب و سایربرادران را از این امور مطلع سازید.» پس بیرون شده، به‌جای دیگر رفت"},{"v":18,"t":"و چون روز شداضطرابی عظیم در سپاهیان افتاد که پطرس را چه شد."},{"v":19,"t":"و هیرودیس چون او را طلبیده نیافت، کشیکچیان را بازخواست نموده، فرمود تا ایشان را به قتل رسانند؛ و خود از یهودیه به قیصریه کوچ کرده، در آنجا اقامت نمود."},{"v":20,"t":"اما هیرودیس با اهل صور و صیدون خشمناک شد. پس ایشان به یکدل نزد او حاضرشدند و بلاستس ناظر خوابگاه پادشاه را با خودمتحد ساخته، طلب مصالحه کردند زیرا که دیارایشان از ملک پادشاه معیشت می‌یافت."},{"v":21,"t":"و درروزی معین، هیرودیس لباس ملوکانه در بر کرد وبر مسند حکومت نشسته، ایشان را خطاب می‌کرد."},{"v":22,"t":"و خلق ندا می‌کردند که آواز خداست نه آواز انسان."},{"v":23,"t":"که در ساعت فرشته خداوند اورا زد زیرا که خدا را تمجید ننمود و کرم او راخورد که بمرد."},{"v":24,"t":"اما کلام خدا نمو کرده، ترقی یافت."},{"v":25,"t":"و برنابا و سولس چون آن خدمت را به انجام رسانیدند، از اورشلیم مراجعت کردند و یوحنای ملقب به مرقس را همراه خود بردند."}],"en":[{"v":1,"t":"Now about that time, King Herod stretched out his hands to oppress some of the assembly."},{"v":2,"t":"He killed James, the brother of John, with the sword."},{"v":3,"t":"When he saw that it pleased the Jews, he proceeded to seize Peter also. This was during the days of unleavened bread."},{"v":4,"t":"When he had arrested him, he put him in prison and delivered him to four squads of four soldiers each to guard him, intending to bring him out to the people after the Passover."},{"v":5,"t":"Peter therefore was kept in the prison, but constant prayer was made by the assembly to God for him."},{"v":6,"t":"The same night when Herod was about to bring him out, Peter was sleeping between two soldiers, bound with two chains. Guards in front of the door kept the prison."},{"v":7,"t":"And behold, an angel of the Lord stood by him, and a light shone in the cell. He struck Peter on the side and woke him up, saying, “Stand up quickly!” His chains fell off his hands."},{"v":8,"t":"The angel said to him, “Get dressed and put on your sandals.” He did so. He said to him, “Put on your cloak and follow me.”"},{"v":9,"t":"And he went out and followed him. He didn’t know that what was being done by the angel was real, but thought he saw a vision."},{"v":10,"t":"When they were past the first and the second guard, they came to the iron gate that leads into the city, which opened to them by itself. They went out and went down one street, and immediately the angel departed from him."},{"v":11,"t":"When Peter had come to himself, he said, “Now I truly know that the Lord has sent out his angel and delivered me out of the hand of Herod, and from everything the Jewish people were expecting.”"},{"v":12,"t":"Thinking about that, he came to the house of Mary, the mother of John who was called Mark, where many were gathered together and were praying."},{"v":13,"t":"When Peter knocked at the door of the gate, a servant girl named Rhoda came to answer."},{"v":14,"t":"When she recognized Peter’s voice, she didn’t open the gate for joy, but ran in and reported that Peter was standing in front of the gate."},{"v":15,"t":"They said to her, “You are crazy!” But she insisted that it was so. They said, “It is his angel.”"},{"v":16,"t":"But Peter continued knocking. When they had opened, they saw him and were amazed."},{"v":17,"t":"But he, beckoning to them with his hand to be silent, declared to them how the Lord had brought him out of the prison. He said, “Tell these things to James and to the brothers.” Then he departed and went to another place."},{"v":18,"t":"Now as soon as it was day, there was no small stir among the soldiers about what had become of Peter."},{"v":19,"t":"When Herod had sought for him and didn’t find him, he examined the guards, then commanded that they should be put to death. He went down from Judea to Caesarea, and stayed there."},{"v":20,"t":"Now Herod was very angry with the people of Tyre and Sidon. They came with one accord to him and, having made Blastus, the king’s personal aide, their friend, they asked for peace, because their country depended on the king’s country for food."},{"v":21,"t":"On an appointed day, Herod dressed himself in royal clothing, sat on the throne, and gave a speech to them."},{"v":22,"t":"The people shouted, “The voice of a god, and not of a man!”"},{"v":23,"t":"Immediately an angel of the Lord struck him, because he didn’t give God the glory. Then he was eaten by worms and died."},{"v":24,"t":"But the word of God grew and multiplied."},{"v":25,"t":"Barnabas and Saul returned to Jerusalem when they had fulfilled their service, also taking with them John who was called Mark."}],"hr":[{"v":1,"t":"U to vrijeme uze Herod zlostavljati neke od Crkve."},{"v":2,"t":"Mačem pogubi Jakova, brata Ivanova."},{"v":3,"t":"Kad vidje da je to drago Židovima, uhvati i Petra (bijahu upravo Dani beskvasnih kruhova)."},{"v":4,"t":"Uhiti ga, baci u tamnicu i dade da ga čuvaju četiri vojničke četverostraže, nakan izvesti ga nakon Pashe pred narod."},{"v":5,"t":"Petra su dakle čuvali u tamnici, a Crkva se svesrdno moljaše Bogu za njega."},{"v":6,"t":"One noći kad ga je Herod kanio privesti, spavao je Petar između dva vojnika, okovan dvojim verigama, a stražari pred vratima čuvahu stražu."},{"v":7,"t":"Kad eto: pojavi se anđeo Gospodnji te svjetlost obasja ćeliju. Anđeo udari Petra u rebra, probudi ga i reče: “Ustaj brzo!” I spadoše mu verige s ruku."},{"v":8,"t":"Anđeo mu reče: “Opaši se i priveži obuću!” On učini tako. Onda će mu anđeo: “Zaogrni se i hajde za mnom!”"},{"v":9,"t":"Petar izađe, pođe za njim, a nije znao da je zbilja što se događa po anđelu: činilo mu se da gleda viđenje."},{"v":10,"t":"Prošavši prvu stražu, i drugu, dođoše do željeznih vrata koja vode u grad. Ona im se sama otvore te oni izađu, prođu jednu ulicu, a onda anđeo odjednom odstupi od njega."},{"v":11,"t":"Petar pak, došavši k sebi, reče: “Sad uistinu znam da je Gospodin poslao anđela svoga i izbavio me iz Herodove ruke i od svega što je očekivao židovski narod.”"},{"v":12,"t":"Kad je to uočio, zaputi se kući Marije, majke Ivana nazvanog Marko. Ondje se mnogi bijahu sabrali i molili."},{"v":13,"t":"Kad Petar pokuca na dvorišna vrata, dođe prisluhnuti sluškinja imenom Ruža."},{"v":14,"t":"Kad prepozna Petrov glas, od radosti i ne otvori vrata, nego utrča i javi da je Petar pred vratima."},{"v":15,"t":"Oni joj rekoše: “Mahnitaš!” Ali je ona uporno tvrdila da je tako. Nato će oni: “Bit će njegov anđeo!”"},{"v":16,"t":"Petar nastavi kucati. Kad napokon otvoriše i ugledaše ga, ostadoše izvan sebe."},{"v":17,"t":"On im rukom mahnu neka šute pa im pripovjedi kako ga Gospodin izvede iz tamnice te dometnu: “Javite to Jakovu i braći!” Onda izađe i ode u drugo mjesto."},{"v":18,"t":"Kad se razdani, nasta među vojnicima uzbuna nemalena što li se s Petrom dogodilo."},{"v":19,"t":"Herod ga stade tražiti, a kad ga ne nađe, sasluša stražare i naredi da se smaknu. Onda siđe iz Judeje u Cezareju i ondje osta."},{"v":20,"t":"A bio je u žestoku sukobu s Tircima i Sidoncima. Oni zajednički dođoše k njemu i pošto pridobiše kraljevskoga komornika Blasta, zaiskaše mir, jer je njihova zemlja dobivala živež od kraljeve."},{"v":21,"t":"U određeni dan sjede Herod odjeven u kraljevsko ruho na prijestol i stade im govoriti."},{"v":22,"t":"Narod izvikivaše: “Božji glas, a ne ljudski!”"},{"v":23,"t":"Umah ga, zbog toga što ne dade slavu Bogu, udari anđeo Gospodnji te on rascrvotočen izdahnu."},{"v":24,"t":"Riječ je pak Božja rasla i širila se."},{"v":25,"t":"Barnaba i Savao, pošto obaviše služenje u Jeruzalemu, vratiše se uzevši sa sobom Ivana zvanog Marko."}]},"13":{"fa":[{"v":1,"t":"و در کلیسایی که در انطاکیه بود انبیا ومعلم چند بودند: برنابا و شمعون ملقب به نیجر و لوکیوس قیروانی و مناحم برادررضاعی هیرودیس تیترارخ و سولس."},{"v":2,"t":"چون ایشان در عبادت خدا و روزه مشغول می‌بودند، روح‌القدس گفت: «برنابا و سولس را برای من جداسازید از بهر آن عمل که ایشان را برای آن خوانده‌ام.»"},{"v":3,"t":"آنگاه روزه گرفته و دعا کرده ودستها بر ایشان گذارده، روانه نمودند."},{"v":4,"t":"پس ایشان از جانب روح‌القدس فرستاده شده، به سلوکیه رفتند و از آنجا از راه دریا به قپرس آمدند."},{"v":5,"t":"و وارد سلامیس شده، در کنایس یهود به کلام خدا موعظه کردند و یوحنا ملازم ایشان بود."},{"v":6,"t":"و چون در تمامی جزیره تا به پافس گشتند، در آنجا شخص یهودی را که جادوگر ونبی کاذب بود یافتند که نام او باریشوع بود."},{"v":7,"t":"اورفیق سرجیوس پولس والی بود که مردی فهیم بود. همان برنابا و سولس را طلب نموده، خواست کلام خدا را بشنود."},{"v":8,"t":"اما علیما یعنی آن جادوگر، زیرا ترجمه اسمش همچنین می‌باشد، ایشان رامخالفت نموده، خواست والی را از ایمان برگرداند."},{"v":9,"t":"ولی سولس که پولس باشد، پر ازروح‌القدس شده، بر او نیک نگریسته،"},{"v":10,"t":"گفت: «ای پر از هر نوع مکر و خباثت، ای فرزند ابلیس ودشمن هر راستی، باز نمی ایستی از منحرف ساختن طرق راست خداوند؟"},{"v":11,"t":"الحال دست خداوند بر توست و کور شده، آفتاب را تا مدتی نخواهی دید.» که در همان ساعت، غشاوه وتاریکی او را فرو گرفت و دور زده، راهنمایی طلب می‌کرد."},{"v":12,"t":"پس والی چون آن ماجرا را دید، از تعلیم خداوند متحیر شده، ایمان آورد."},{"v":13,"t":"آنگاه پولس و رفقایش از پافس به کشتی سوار شده، به پرجه پمفلیه آمدند. اما یوحنا ازایشان جدا شده، به اورشلیم برگشت."},{"v":14,"t":"و ایشان از پرجه عبور نموده، به انطاکیه پیسیدیه آمدند ودر روز سبت به کنیسه درآمده، بنشستند."},{"v":15,"t":"وبعد از تلاوت تورات و صحف انبیا، روسای کنیسه نزد ایشان فرستاده، گفتند: «ای برادران عزیز، اگر کلامی نصیحت‌آمیز برای قوم دارید، بگویید.»"},{"v":16,"t":"پس پولس برپا ایستاده، به‌دست خوداشاره کرده، گفت: «ای مردان اسرائیلی وخداترسان، گوش دهید!"},{"v":17,"t":"خدای این قوم، اسرائیل، پدران ما را برگزیده، قوم را در غربت ایشان در زمین مصر سرافراز نمود و ایشان را به بازوی بلند از آنجا بیرون آورد؛"},{"v":18,"t":"و قریب به چهل سال در بیابان متحمل حرکات ایشان می‌بود."},{"v":19,"t":"و هفت طایفه را در زمین کنعان هلاک کرده، زمین آنها را میراث ایشان ساخت تا قریب چهار صد و پنجاه سال."},{"v":20,"t":"و بعد از آن بدیشان داوران داد تا زمان سموئیل نبی."},{"v":21,"t":"و از آن وقت پادشاهی خواستند و خدا شاول بن قیس را ازسبط بنیامین تا چهل سال به ایشان داد."},{"v":22,"t":"پس اورا از میان برداشته، داود را برانگیخت تا پادشاه ایشان شود و در حق او شهادت داد که “داود بن یسی را مرغوب دل خود یافته‌ام که به تمامی اراده من عمل خواهد کرد.”"},{"v":23,"t":"و از ذریت او خدابرحسب وعده، برای اسرائیل نجات‌دهنده‌ای یعنی عیسی را آورد،"},{"v":24,"t":"چون یحیی پیش ازآمدن او تمام قوم اسرائیل را به تعمید توبه موعظه نموده بود."},{"v":25,"t":"پس چون یحیی دوره خودرا به پایان برد، گفت: “مرا که می‌پندارید؟ من اونیستم، لکن اینک بعد از من کسی می‌آید که لایق گشادن نعلین او نیم.”"},{"v":26,"t":"«ای برادران عزیز و ابنای آل ابراهیم وهرکه از شما خداترس باشد، مر شما را کلام این نجات فرستاده شد."},{"v":27,"t":"زیرا سکنه اورشلیم وروسای ایشان، چونکه نه او را شناختند و نه آوازهای انبیا را که هر سبت خوانده می‌شود، بروی فتوی دادند و آنها را به اتمام رسانیدند."},{"v":28,"t":"وهر‌چند هیچ علت قتل در وی نیافتند، از پیلاطس خواهش کردند که او کشته شود."},{"v":29,"t":"پس چون آنچه درباره وی نوشته شده بود تمام کردند، او رااز صلیب پایین آورده، به قبر سپردند."},{"v":30,"t":"لکن خدااو را از مردگان برخیزانید."},{"v":31,"t":"و او روزهای بسیار ظاهر شد بر آنانی که همراه او از جلیل به اورشلیم آمده بودند که الحال نزد قوم شهود او می‌باشند."},{"v":32,"t":"پس ما به شما بشارت می‌دهیم، بدان وعده‌ای که به پدران ما داده شد،"},{"v":33,"t":"که خدا آن را به ما که فرزندان ایشان می‌باشیم وفا کرد، وقتی که عیسی را برانگیخت، چنانکه در زبور دوم مکتوب است که “تو پسر من هستی، من امروز تو را تولیدنمودم.”"},{"v":34,"t":"و در آنکه او را از مردگان برخیزانید تادیگر هرگز راجع به فساد نشود چنین گفت که “به برکات قدوس و امین داود برای شما وفا خواهم کرد.”"},{"v":35,"t":"بنابراین در جایی دیگر نیز می‌گوید: “توقدوس خود را نخواهی گذاشت که فساد را بیند.”"},{"v":36,"t":"زیرا که داود چونکه در زمان خود اراده خدا راخدمت کرده بود، به خفت و به پدران خود ملحق شده، فساد را دید."},{"v":37,"t":"لیکن آن کس که خدا او رابرانگیخت، فساد را ندید."},{"v":38,"t":"«پس‌ای برادران عزیز، شما را معلوم باد که به وساطت او به شما از آمرزش گناهان اعلام می‌شود."},{"v":39,"t":"و به وسیله او هر‌که ایمان آورد، عادل شمرده می‌شود، از هر چیزی که به شریعت موسی نتوانستید عادل شمرده شوید."},{"v":40,"t":"پس احتیاط کنید، مبادا آنچه در صحف انبیامکتوب است، بر شما واقع شود،"},{"v":41,"t":"که “ای حقیرشمارندگان، ملاحظه کنید و تعجب نمایید و هلاک شوید زیرا که من عملی را درایام شما پدید آرم، عملی که هر‌چند کسی شما را از آن اعلام نماید، تصدیق نخواهیدکرد.»"},{"v":42,"t":"پس چون از کنیسه بیرون می‌رفتند، خواهش نمودند که در سبت آینده هم این سخنان را بدیشان بازگویند."},{"v":43,"t":"و چون اهل کنیسه متفرق شدند، بسیاری از یهودیان و جدیدان خداپرست از عقب پولس و برنابا افتادند؛ و آن دو نفر به ایشان سخن گفته، ترغیب می‌نمودند که به فیض خداثابت باشید."},{"v":44,"t":"اما در سبت دیگر قریب به تمامی شهر فراهم شدند تا کلام خدا را بشنوند."},{"v":45,"t":"ولی چون یهود ازدحام خلق را دیدند، از حسد پرگشتند و کفر گفته، با سخنان پولس مخالفت کردند."},{"v":46,"t":"آنگاه پولس و برنابا دلیر شده، گفتند: «واجب بود کلام خدا نخست به شما القا شود. لیکن چون آن را رد کردید و خود را ناشایسته حیات جاودانی شمردید، همانا به سوی امت هاتوجه نماییم."},{"v":47,"t":"زیرا خداوند به ما چنین امرفرمود که “تو را نور امت‌ها ساختم تا الی اقصای زمین منشا نجات باشی.”»"},{"v":48,"t":"چون امت‌ها این راشنیدند، شادخاطر شده، کلام خداوند را تمجیدنمودند و آنانی که برای حیات جاودانی مقرربودند، ایمان آوردند."},{"v":49,"t":"و کلام خدا در تمام آن نواحی منتشرگشت."},{"v":50,"t":"اما یهودیان چند زن دیندار و متشخص و اکابر شهر را بشورانیدند و ایشان را به زحمت رسانیدن بر پولس و برنابا تحریض نموده، ایشان را از حدود خود بیرون کردند."},{"v":51,"t":"و ایشان خاک پایهای خود را بر ایشان افشانده، به ایقونیه آمدند."},{"v":52,"t":"و شاگردان پر از خوشی و روح‌القدس گردیدند."}],"en":[{"v":1,"t":"Now in the assembly that was at Antioch there were some prophets and teachers: Barnabas, Simeon who was called Niger, Lucius of Cyrene, Manaen the foster brother of Herod the tetrarch, and Saul."},{"v":2,"t":"As they served the Lord and fasted, the Holy Spirit said, “Separate Barnabas and Saul for me, for the work to which I have called them.”"},{"v":3,"t":"Then, when they had fasted and prayed and laid their hands on them, they sent them away."},{"v":4,"t":"So, being sent out by the Holy Spirit, they went down to Seleucia. From there they sailed to Cyprus."},{"v":5,"t":"When they were at Salamis, they proclaimed God’s word in the Jewish synagogues. They also had John as their attendant."},{"v":6,"t":"When they had gone through the island to Paphos, they found a certain sorcerer, a false prophet, a Jew whose name was Bar Jesus,"},{"v":7,"t":"who was with the proconsul, Sergius Paulus, a man of understanding. This man summoned Barnabas and Saul, and sought to hear the word of God."},{"v":8,"t":"But Elymas the sorcerer (for so is his name by interpretation) withstood them, seeking to turn the proconsul away from the faith."},{"v":9,"t":"But Saul, who is also called Paul, filled with the Holy Spirit, fastened his eyes on him"},{"v":10,"t":"and said, “You son of the devil, full of all deceit and all cunning, you enemy of all righteousness, will you not cease to pervert the right ways of the Lord?"},{"v":11,"t":"Now, behold, the hand of the Lord is on you, and you will be blind, not seeing the sun for a season!” Immediately a mist and darkness fell on him. He went around seeking someone to lead him by the hand."},{"v":12,"t":"Then the proconsul, when he saw what was done, believed, being astonished at the teaching of the Lord."},{"v":13,"t":"Now Paul and his company set sail from Paphos and came to Perga in Pamphylia. John departed from them and returned to Jerusalem."},{"v":14,"t":"But they, passing on from Perga, came to Antioch of Pisidia. They went into the synagogue on the Sabbath day and sat down."},{"v":15,"t":"After the reading of the law and the prophets, the rulers of the synagogue sent to them, saying, “Brothers, if you have any word of exhortation for the people, speak.”"},{"v":16,"t":"Paul stood up, and gesturing with his hand said, “Men of Israel, and you who fear God, listen."},{"v":17,"t":"The God of this people chose our fathers, and exalted the people when they stayed as aliens in the land of Egypt, and with an uplifted arm, he led them out of it."},{"v":18,"t":"For a period of about forty years he put up with them in the wilderness."},{"v":19,"t":"When he had destroyed seven nations in the land of Canaan, he gave them their land for an inheritance for about four hundred fifty years."},{"v":20,"t":"After these things, he gave them judges until Samuel the prophet."},{"v":21,"t":"Afterward they asked for a king, and God gave to them Saul the son of Kish, a man of the tribe of Benjamin, for forty years."},{"v":22,"t":"When he had removed him, he raised up David to be their king, to whom he also testified, ‘I have found David the son of Jesse, a man after my heart, who will do all my will.’"},{"v":23,"t":"From this man’s offspring, God has brought salvation to Israel according to his promise,"},{"v":24,"t":"before his coming, when John had first preached the baptism of repentance to Israel."},{"v":25,"t":"As John was fulfilling his course, he said, ‘What do you suppose that I am? I am not he. But behold, one comes after me, the sandals of whose feet I am not worthy to untie.’"},{"v":26,"t":"“Brothers, children of the stock of Abraham, and those among you who fear God, the word of this salvation is sent out to you."},{"v":27,"t":"For those who dwell in Jerusalem, and their rulers, because they didn’t know him, nor the voices of the prophets which are read every Sabbath, fulfilled them by condemning him."},{"v":28,"t":"Though they found no cause for death, they still asked Pilate to have him killed."},{"v":29,"t":"When they had fulfilled all things that were written about him, they took him down from the tree and laid him in a tomb."},{"v":30,"t":"But God raised him from the dead,"},{"v":31,"t":"and he was seen for many days by those who came up with him from Galilee to Jerusalem, who are his witnesses to the people."},{"v":32,"t":"We bring you good news of the promise made to the fathers,"},{"v":33,"t":"that God has fulfilled this to us, their children, in that he raised up Jesus. As it is also written in the second psalm, ‘You are my Son. Today I have become your father.’"},{"v":34,"t":"“Concerning that he raised him up from the dead, now no more to return to corruption, he has spoken thus: ‘I will give you the holy and sure blessings of David.’"},{"v":35,"t":"Therefore he says also in another psalm, ‘You will not allow your Holy One to see decay.’"},{"v":36,"t":"For David, after he had in his own generation served the counsel of God, fell asleep, was laid with his fathers, and saw decay."},{"v":37,"t":"But he whom God raised up saw no decay."},{"v":38,"t":"Be it known to you therefore, brothers, that through this man is proclaimed to you remission of sins;"},{"v":39,"t":"and by him everyone who believes is justified from all things, from which you could not be justified by the law of Moses."},{"v":40,"t":"Beware therefore, lest that come on you which is spoken in the prophets:"},{"v":41,"t":"‘Behold, you scoffers! Wonder and perish, for I work a work in your days, a work which you will in no way believe, if one declares it to you.’”"},{"v":42,"t":"So when the Jews went out of the synagogue, the Gentiles begged that these words might be preached to them the next Sabbath."},{"v":43,"t":"Now when the synagogue broke up, many of the Jews and of the devout proselytes followed Paul and Barnabas; who, speaking to them, urged them to continue in the grace of God."},{"v":44,"t":"The next Sabbath, almost the whole city was gathered together to hear the word of God."},{"v":45,"t":"But when the Jews saw the multitudes, they were filled with jealousy, and contradicted the things which were spoken by Paul, and blasphemed."},{"v":46,"t":"Paul and Barnabas spoke out boldly, and said, “It was necessary that God’s word should be spoken to you first. Since indeed you thrust it from yourselves, and judge yourselves unworthy of eternal life, behold, we turn to the Gentiles."},{"v":47,"t":"For so has the Lord commanded us, saying, ‘I have set you as a light for the Gentiles, that you should bring salvation to the uttermost parts of the earth.’”"},{"v":48,"t":"As the Gentiles heard this, they were glad and glorified the word of God. As many as were appointed to eternal life believed."},{"v":49,"t":"The Lord’s word was spread abroad throughout all the region."},{"v":50,"t":"But the Jews stirred up the devout and prominent women and the chief men of the city, and stirred up a persecution against Paul and Barnabas, and threw them out of their borders."},{"v":51,"t":"But they shook off the dust of their feet against them, and came to Iconium."},{"v":52,"t":"The disciples were filled with joy and with the Holy Spirit."}],"hr":[{"v":1,"t":"U antiohijskoj je Crkvi bilo proroka i učitelja: Barnaba, Šimun zvani Niger, Lucije Cirenac, Manahen, suothranjenik Heroda četverovlasnika, i Savao."},{"v":2,"t":"Dok su jednom obavljali službu Božju i postili, reče Duh Sveti: “De mi odlučite Barnabu i Savla za djelo na koje sam ih pozvao.”"},{"v":3,"t":"Onda su postili, molili, položili na njih ruke i otpustili ih."},{"v":4,"t":"Poslani od Svetoga Duha siđu u Seleuciju, a odande odjedre na Cipar."},{"v":5,"t":"Kad se nađoše u Salamini, navješćivahu riječ Božju u židovskim sinagogama. Imali su i Ivana za poslužitelja."},{"v":6,"t":"Pošto pak prođoše sav otok do Pafa, nađoše nekog vračara, nazoviproroka, Židova, imenom Barjesu."},{"v":7,"t":"On bijaše uz namjesnika Sergija Pavla, čovjeka razborita. Sergije dozva Barnabu i Savla te zaiska čuti riječ Božju,"},{"v":8,"t":"ali im se usprotivi Elim, Vračar - tako mu se ime prevodi - nastojeći odvratiti namjesnika od vjere."},{"v":9,"t":"Savao pak, zvan i Pavao, pun Duha Svetoga, ošinu ga pogledom"},{"v":10,"t":"i reče: “Pun svake lukavosti i prevrtljivosti, sine đavolski, neprijatelju svake pravednosti, zar nikako da prestaneš iskrivljavati ravne putove Gospodnje?"},{"v":11,"t":"Evo stoga sada ruke Gospodnje na tebi: oslijepljet ćeš i neko vrijeme nećeš gledati sunca!” Odmah pade na nj mrak i tama te on glavinjajući stade tražiti ruke vodilje."},{"v":12,"t":"Videći što se dogodilo, povjerova tada namjesnik, zanesen naukom Gospodnjim."},{"v":13,"t":"Pošto se Pavao i oni oko njega otisnuše od Pafa, stigoše u Pergu pamfilijsku. Ivan ih napusti te se vrati u Jeruzalem."},{"v":14,"t":"Oni pak krenuše iz Perge i stigoše u Antiohiju pizidijsku. U dan subotni ušli su u sinagogu i sjeli."},{"v":15,"t":"Nakon čitanja Zakona i Proroka pošalju nadstojnici sinagoge k njima: “Braćo, rekoše, ima li u vas koja riječ utjehe za narod, govorite!”"},{"v":16,"t":"Nato usta Pavao, dadne rukom znak i reče: “Izraelci i vi koji se Boga bojite, čujte!"},{"v":17,"t":"Bog naroda ovoga, Izraela, izabra oce naše i uzdiže narod za boravka u zemlji egipatskoj te ga ispruženom rukom izvede iz nje."},{"v":18,"t":"Oko četrdeset ga je godina na rukama nosio u pustinji"},{"v":19,"t":"pa pošto zatre sedam naroda u zemlji kanaanskoj, ubaštini ga u zemlji njihovoj"},{"v":20,"t":"za kakve četiri stotine i pedeset godina. Nakon toga dade im suce - do Samuela proroka."},{"v":21,"t":"Onda zaiskaše kralja pa im Bog za četrdeset godina dade Šaula, sina Kiševa, iz plemena Benjaminova."},{"v":22,"t":"Pošto svrgnu njega, podiže im za kralja Davida za kojega posvjedoči: Nađoh Davida, sina Jišajeva, čovjeka po svom srcu, koji će ispuniti sve moje želje."},{"v":23,"t":"Iz njegova potomstva izvede Bog po svom obećanju Izraelu Spasitelja, Isusa."},{"v":24,"t":"Pred njegovim je dolaskom Ivan propovijedao krštenje obraćenja svemu narodu izraelskomu."},{"v":25,"t":"A kad je Ivan dovršavao svoju trku, govorio je: 'Nisam ja onaj za koga me vi držite. Nego za mnom evo dolazi onaj komu ja nisam dostojan odriješiti obuće na nogama.'”"},{"v":26,"t":"“Braćo, sinovi roda Abrahamova, vi i oni koji se među vama Boga boje, nama je upravljena ova Riječ spasenja."},{"v":27,"t":"Doista, žitelji Jeruzalema i glavari njihovi ne upoznaše njega ni riječi proročkih što se čitaju svake subote pa ih, osudivši ga, ispuniše."},{"v":28,"t":"Premda ne nađoše nikakva razloga smrti, zatražiše od Pilata da ga smakne."},{"v":29,"t":"Pošto pak izvršiše sve što je o njemu napisano, skinuše ga s drveta i položiše u grob."},{"v":30,"t":"Ali Bog ga uskrisi od mrtvih."},{"v":31,"t":"On se mnogo dana ukazivao onima koji s njim bijahu uzašli iz Galileje u Jeruzalem. Oni su sada njegovi svjedoci pred narodom.”"},{"v":32,"t":"“I mi vam navješćujemo evanđelje: obećanje dano ocima"},{"v":33,"t":"Bog je ispunio djeci, nama, uskrisivši Isusa, kao što je i pisano u Psalmu drugom: Ti si Sin moj, danas te rodih."},{"v":34,"t":"Da ga pak uskrisi od mrtvih te se on više nikad neće vratiti u trulež, rekao je ovime: Dat ću vama svetinje Davidove, pouzdane."},{"v":35,"t":"Zato i na drugome mjestu kaže: Nećeš dati da Svetac tvoj ugleda truleži."},{"v":36,"t":"David doista, pošto u svom naraštaju posluži volji Božjoj, preminu, pridruži se ocima svojim i vidje trulež,"},{"v":37,"t":"a Onaj koga Bog uskrisi ne vidje truleži."},{"v":38,"t":"/"},{"v":39,"t":"Neka vam dakle braćo, znano bude: po Ovome vam se navješćuje oproštenje grijeha! Po Ovome se tko god vjeruje, opravdava od svega od čega se po Mojsijevu zakonu niste mogli opravdati!"},{"v":40,"t":"Pazite da se ne zbude što je rečeno u Prorocima:"},{"v":41,"t":"Obazrite se, preziratelji, snebijte se i nestanite! Jer djelo činim u dane vaše, djelo u koje ne biste vjerovali da vam ga tko ispriča.”"},{"v":42,"t":"Na izlasku su ih molili da im iduće subote o tome govore."},{"v":43,"t":"A pošto se skup raspustio, mnogi Židovi i bogobojazne pridošlice pođoše za Pavlom i Barnabom koji su ih nagovarali ustrajati u milosti Božjoj."},{"v":44,"t":"Iduće se subote gotovo sav grad zgrnu čuti riječ Gospodnju."},{"v":45,"t":"Kad su Židovi ugledali mnoštvo, puni zavisti psujući suprotstavljali su se onomu što je Pavao govorio."},{"v":46,"t":"Na to im Pavao i Barnaba smjelo rekoše: “Trebalo je da se najprije vama navijesti riječ Božja. Ali kad je odbacujete i sami sebe ne smatrate dostojnima života vječnoga, obraćamo se evo poganima."},{"v":47,"t":"Jer ovako nam je zapovjedio Gospodin: Postavih te za svjetlost poganima, da budeš na spasenje do nakraj zemlje."},{"v":48,"t":"Pogani koji su slušali radovali su se i slavili riječ Gospodnju te povjerovaše oni koji bijahu određeni za život vječni."},{"v":49,"t":"Riječ se pak Gospodnja pronese po svoj onoj pokrajini."},{"v":50,"t":"Ali Židovi potakoše ugledne bogobojazne žene i prvake gradske te zametnuše progon protiv Pavla i Barnabe pa ih izbaciše iz svoga kraja."},{"v":51,"t":"Oni pak stresu prašinu s nogu protiv njih pa odu u Ikonij."},{"v":52,"t":"A učenici su se ispunjali radošću i Duhom Svetim."}]},"14":{"fa":[{"v":1,"t":"اما در ایقونیه، ایشان با هم به کنیسه یهود در‌آمده، به نوعی سخن‌گفتند که جمعی کثیر از یهود و یونانیان ایمان آوردند."},{"v":2,"t":"لیکن یهودیان بی‌ایمان دلهای امت‌ها را اغوانمودند و با برادران بداندیش ساختند."},{"v":3,"t":"پس مدت مدیدی توقف نموده، به نام خداوندی که به کلام فیض خود شهادت می‌داد، به دلیری سخن می‌گفتند و او آیات و معجزات عطا می‌کرد که ازدست ایشان ظاهر شود."},{"v":4,"t":"و مردم شهر دو فرقه شدند، گروهی همداستان یهود و جمعی با رسولان بودند."},{"v":5,"t":"وچون امت‌ها و یهود با روسای خود بر ایشان هجوم می‌آوردند تا ایشان را افتضاح نموده، سنگسار کنند،"},{"v":6,"t":"آگاهی یافته، به سوی لستره ودربه شهرهای لیکاونیه و دیار آن نواحی فرارکردند."},{"v":7,"t":"و در آنجا بشارت می‌دادند."},{"v":8,"t":"و در لستره مردی نشسته بود که پایهایش بی‌حرکت بود و از شکم مادر، لنگ متولد شده، هرگز راه نرفته بود."},{"v":9,"t":"چون او سخن پولس رامی شنید، او بر وی نیک نگریسته، دید که ایمان شفا یافتن را دارد."},{"v":10,"t":"پس به آواز بلند بدو گفت: «بر پایهای خود راست بایست.» که در ساعت برجسته، خرامان گردید."},{"v":11,"t":"اما خلق چون این عمل پولس را دیدند، صدای خود را به زبان لیکاونیه بلند کرده، گفتند: «خدایان به صورت انسان نزد مانازل شده‌اند.»"},{"v":12,"t":"پس برنابا را مشتری و پولس راعطارد خواندند زیرا که او در سخن‌گفتن مقدم بود."},{"v":13,"t":"پس کاهن مشتری که پیش شهر ایشان بود، گاوان و تاجها با گروه هایی از خلق به دروازه هاآورده، خواست که قربانی گذراند."},{"v":14,"t":"اما چون آن دو رسول یعنی برنابا و پولس شنیدند، جامه های خود را دریده، در میان مردم افتادند و ندا کرده،"},{"v":15,"t":"گفتند: «ای مردمان، چرا چنین می‌کنید؟ ما نیزانسان و صاحبان علتها مانند شما هستیم و به شمابشارت می‌دهیم که از این اباطیل رجوع کنید به سوی خدای حی که آسمان و زمین و دریا و آنچه را که در آنها است آفرید،"},{"v":16,"t":"که در طبقات سلف همه امت‌ها را واگذاشت که در طرق خود رفتارکنند،"},{"v":17,"t":"با وجودی که خود را بی‌شهادت نگذاشت، چون احسان می‌نمود و از آسمان باران بارانیده و فصول بارآور بخشیده، دلهای ما را ازخوراک و شادی پر می‌ساخت.»"},{"v":18,"t":"و بدین سخنان خلق را از گذرانیدن قربانی برای ایشان به دشواری باز داشتند."},{"v":19,"t":"اما یهودیان از انطاکیه و ایقونیه آمده، مردم را با خود متحد ساختند و پولس را سنگسارکرده، از شهر بیرون کشیدند و پنداشتند که مرده است."},{"v":20,"t":"اما چون شاگردان گرد او ایستادندبرخاسته، به شهر درآمد و فردای آن روز با برنابابه سوی دربه روانه شد"},{"v":21,"t":"و در آن شهر بشارت داده، بسیاری را شاگرد ساختند. پس به لستره وایقونیه و انطاکیه مراجعت کردند."},{"v":22,"t":"و دلهای شاگردان را تقویت داده، پند می‌دادند که در ایمان ثابت بمانند و اینکه با مصیبتهای بسیار می‌بایدداخل ملکوت خدا گردیم."},{"v":23,"t":"و در هر کلیسابجهت ایشان کشیشان معین نمودند و دعا و روزه داشته، ایشان را به خداوندی که بدو ایمان آورده بودند، سپردند."},{"v":24,"t":"و از پیسیدیه گذشته به پمفلیه آمدند."},{"v":25,"t":"و در پرجه به کلام موعظه نمودند و به اتالیه فرود آمدند."},{"v":26,"t":"و از آنجا به کشتی سوار شده، به انطاکیه آمدند که از همان جا ایشان را به فیض خدا سپرده بودند برای آن کاری که به انجام رسانیده بودند."},{"v":27,"t":"و چون وارد شهر شدند کلیسا را جمع کرده، ایشان را مطلع ساختند از آنچه خدا با ایشان کرده بود و چگونه دروازه ایمان را برای امت‌ها باز کرده بود."},{"v":28,"t":"پس مدت مدیدی با شاگردان بسر بردند."}],"en":[{"v":1,"t":"In Iconium, they entered together into the synagogue of the Jews, and so spoke that a great multitude both of Jews and of Greeks believed."},{"v":2,"t":"But the disbelieving Jews stirred up and embittered the souls of the Gentiles against the brothers."},{"v":3,"t":"Therefore they stayed there a long time, speaking boldly in the Lord, who testified to the word of his grace, granting signs and wonders to be done by their hands."},{"v":4,"t":"But the multitude of the city was divided. Part sided with the Jews and part with the apostles."},{"v":5,"t":"When some of both the Gentiles and the Jews, with their rulers, made a violent attempt to mistreat and stone them,"},{"v":6,"t":"they became aware of it and fled to the cities of Lycaonia, Lystra, Derbe, and the surrounding region."},{"v":7,"t":"There they preached the Good News."},{"v":8,"t":"At Lystra a certain man sat, impotent in his feet, a cripple from his mother’s womb, who never had walked."},{"v":9,"t":"He was listening to Paul speaking, who, fastening eyes on him and seeing that he had faith to be made whole,"},{"v":10,"t":"said with a loud voice, “Stand upright on your feet!” He leaped up and walked."},{"v":11,"t":"When the multitude saw what Paul had done, they lifted up their voice, saying in the language of Lycaonia, “The gods have come down to us in the likeness of men!”"},{"v":12,"t":"They called Barnabas “Jupiter”, and Paul “Mercury”, because he was the chief speaker."},{"v":13,"t":"The priest of Jupiter, whose temple was in front of their city, brought oxen and garlands to the gates, and would have made a sacrifice along with the multitudes."},{"v":14,"t":"But when the apostles, Barnabas and Paul, heard of it, they tore their clothes and sprang into the multitude, crying out,"},{"v":15,"t":"“Men, why are you doing these things? We also are men of the same nature as you, and bring you good news, that you should turn from these vain things to the living God, who made the sky, the earth, the sea, and all that is in them;"},{"v":16,"t":"who in the generations gone by allowed all the nations to walk in their own ways."},{"v":17,"t":"Yet he didn’t leave himself without witness, in that he did good and gave you rains from the sky and fruitful seasons, filling our hearts with food and gladness.”"},{"v":18,"t":"Even saying these things, they hardly stopped the multitudes from making a sacrifice to them."},{"v":19,"t":"But some Jews from Antioch and Iconium came there, and having persuaded the multitudes, they stoned Paul and dragged him out of the city, supposing that he was dead."},{"v":20,"t":"But as the disciples stood around him, he rose up, and entered into the city. On the next day he went out with Barnabas to Derbe."},{"v":21,"t":"When they had preached the Good News to that city and had made many disciples, they returned to Lystra, Iconium, and Antioch,"},{"v":22,"t":"strengthening the souls of the disciples, exhorting them to continue in the faith, and that through many afflictions we must enter into God’s Kingdom."},{"v":23,"t":"When they had appointed elders for them in every assembly, and had prayed with fasting, they commended them to the Lord on whom they had believed."},{"v":24,"t":"They passed through Pisidia and came to Pamphylia."},{"v":25,"t":"When they had spoken the word in Perga, they went down to Attalia."},{"v":26,"t":"From there they sailed to Antioch, from where they had been committed to the grace of God for the work which they had fulfilled."},{"v":27,"t":"When they had arrived and had gathered the assembly together, they reported all the things that God had done with them, and that he had opened a door of faith to the nations."},{"v":28,"t":"They stayed there with the disciples for a long time."}],"hr":[{"v":1,"t":"U Ikoniju isto tako uđoše u židovsku sinagogu i govorahu tako da povjerova veliko mnoštvo Židova i Grka."},{"v":2,"t":"Ali nepokorni Židovi razdražiše i podjariše pogane protiv braće."},{"v":3,"t":"Oni se ipak zadržaše duže vremena, smjeli u Gospodinu koji je svjedočio za Riječ milosti svoje, davao da se po njihovim rukama događaju znamenja i čudesa."},{"v":4,"t":"Mnoštvo se gradsko podvoji: jedni bijahu za Židove, drugi za apostole."},{"v":5,"t":"Pogani i Židovi sa svojim glavarima navališe da zlostave i kamenuju apostole."},{"v":6,"t":"Kada to opaziše, prebjegoše oni u likaonske gradove Listru i Derbu i okolicu."},{"v":7,"t":"Ondje su navješćivali evanđelje."},{"v":8,"t":"U Listri je sjedio neki čovjek uzetih nogu, hrom od majčine utrobe; nikada nije hodao."},{"v":9,"t":"Čuo je Pavla gdje govori."},{"v":10,"t":"Pavao ga pronikne pogledom, vidje da ima vjeru u spasenje pa mu iza glasa reče: “Uspravi se na noge!” On skoči i prohoda."},{"v":11,"t":"Kad mnoštvo ugleda što učini Pavao, povika likaonski: “Bogovi u ljudskom obličju siđoše k nama!”"},{"v":12,"t":"I nazvaše Barnabu Zeusom, a Pavla Hermesom jer je Pavao vodio riječ."},{"v":13,"t":"A svećenik Zeusa Predgradskoga dovede pred vrata bikove i vijence te u zajednici s narodom htjede žrtvovati."},{"v":14,"t":"Kada su to dočuli apostoli Barnaba i Pavao, razdriješe haljine i uletješe u narod vičući:"},{"v":15,"t":"“Ljudi, što to radite? I mi smo smrtnici, baš kao i vi! Navješćujemo vam da se od tih ispraznosti obratite k Bogu živomu koji stvori nebo i zemlju, more i sve što je u njima."},{"v":16,"t":"On je u prošlim naraštajima pustio da svi pogani pođu svojim putovima."},{"v":17,"t":"Ipak ne ostavi sebe neposvjedočena: dobročinstva iskazuje, s neba vam kišu daje i vremena plodonosna, napunja hranom i radošću srca vaša.”"},{"v":18,"t":"I tako govoreći, jedva sklonuše mnoštvo da im ne žrtvuje."},{"v":19,"t":"Uto iz Antiohije i Ikonija nadođu neki Židovi, pridobiju svjetinu te kamenuju Pavla i odvuku ga izvan grada misleći da je mrtav."},{"v":20,"t":"Kad ga pak okružiše učenici, usta on i uđe u grad. Sutradan ode s Barnabom u Derbu."},{"v":21,"t":"Pošto navijestiše evanđelje tomu gradu i mnoge učiniše učenicima, vratiše se u Listru, u Ikonij i u Antiohiju."},{"v":22,"t":"Učvršćivali su duše učenika bodreći ih da ustraju u vjeri jer da nam je kroz mnoge nevolje ući u kraljevstvo Božje."},{"v":23,"t":"Postavljali su im po crkvama starješine te ih, nakon molitve i posta, povjeravahu Gospodinu u kojega su povjerovali."},{"v":24,"t":"Pošto su prešli Pizidiju, stigoše u Pamfiliju."},{"v":25,"t":"U Pergi navijestiše Riječ pa siđu u Ataliju."},{"v":26,"t":"Odande pak odjedriše u Antiohiju, odakle ono bijahu povjereni milosti Božjoj za djelo koje izvršiše."},{"v":27,"t":"Kada stigoše, sabraše Crkvu i pripovjediše što sve učini Bog po njima: da i poganima otvori vrata vjere."},{"v":28,"t":"I proveli su nemalo vremena s učenicima."}]},"15":{"fa":[{"v":1,"t":"و تنی چند از یهودیه آمده، برادران راتعلیم می‌دادند که «اگر برحسب آیین موسی مختون نشوید، ممکن نیست که نجات یابید.»"},{"v":2,"t":"چون پولس و برنابا را منازعه و مباحثه بسیار با ایشان واقع شد، قرار بر این شد که پولس و برنابا و چند نفر دیگر از ایشان نزد رسولان وکشیشان در اورشلیم برای این مساله بروند."},{"v":3,"t":"پس کلیسا ایشان را مشایعت نموده از فینیقیه و سامره عبور کرده، ایمان آوردن امت‌ها را بیان کردند وهمه برادران را شادی عظیم دادند."},{"v":4,"t":"و چون وارد اورشلیم شدند، کلیسا ورسولان و کشیشان ایشان را پذیرفتند و آنها را ازآنچه خدا با ایشان کرده بود، خبر دادند."},{"v":5,"t":"آنگاه بعضی از فرقه فریسیان که ایمان آورده بودند، برخاسته، گفتند: «اینها را باید ختنه نمایند و امر کنند که سنن موسی را نگاه دارند.»"},{"v":6,"t":"پس رسولان و کشیشان جمع شدند تا در این امر مصلحت بینند."},{"v":7,"t":"و چون مباحثه سخت شد، پطرس برخاسته، بدیشان گفت: «ای برادران عزیز، شما آگاهید که از ایام اول، خدا از میان شمااختیار کرد که امت‌ها از زبان من کلام بشارت رابشنوند و ایمان آورند."},{"v":8,"t":"و خدای عارف‌القلوب بر ایشان شهادت داد بدین که روح‌القدس رابدیشان داد، چنانکه به ما نیز."},{"v":9,"t":"و در میان ما وایشان هیچ فرق نگذاشت، بلکه محض ایمان دلهای ایشان را طاهر نمود."},{"v":10,"t":"پس اکنون چراخدا را امتحان می‌کنید که یوغی بر گردن شاگردان می‌نهید که پدران ما و ما نیز طاقت تحمل آن رانداشتیم،"},{"v":11,"t":"بلکه اعتقاد داریم که محض فیض خداوند عیسی مسیح نجات خواهیم یافت، همچنان‌که ایشان نیز.»"},{"v":12,"t":"پس تمام جماعت ساکت شده، به برنابا وپولس گوش گرفتند چون آیات و معجزات رابیان می‌کردند که خدا در میان امت‌ها به وساطت ایشان ظاهر ساخته بود."},{"v":13,"t":"پس چون ایشان ساکت شدند، یعقوب رو آورده، گفت: «ای برادران عزیز، مرا گوش گیرید."},{"v":14,"t":"شمعون بیان کرده است که چگونه خدا اول امت‌ها را تفقدنمود تا قومی از ایشان به نام خود بگیرد."},{"v":15,"t":"وکلام انبیا در این مطابق است چنانکه مکتوب است"},{"v":16,"t":"که «بعد از این رجوع نموده، خیمه داود را که افتاده است باز بنا می‌کنم و خرابیهای آن را باز بنامی کنم و آن را برپا خواهم کرد،"},{"v":17,"t":"تا بقیه مردم طالب خداوند شوند و جمیع امت هایی که بر آنهانام من نهاده شده است.»"},{"v":18,"t":"این را می‌گوید خداوندی که این چیزها را از بدو عالم معلوم کرده است."},{"v":19,"t":"پس رای من این است: کسانی را که ازامت‌ها به سوی خدا بازگشت می‌کنند زحمت نرسانیم،"},{"v":20,"t":"مگر اینکه ایشان را حکم کنیم که ازنجاسات بتها و زنا و حیوانات خفه شده و خون بپرهیزند."},{"v":21,"t":"زیرا که موسی از طبقات سلف در هرشهر اشخاصی دارد که بدو موعظه می‌کنند، چنانکه در هر سبت در کنایس او را تلاوت می‌کنند.»"},{"v":22,"t":"آنگاه رسولان و کشیشان با تمامی کلیسابدین رضا دادند که چند نفر از میان خود انتخاب نموده، همراه پولس و برنابا به انطاکیه بفرستند، یعنی یهودای ملقب به برسابا و سیلاس که ازپیشوایان برادران بودند."},{"v":23,"t":"و بدست ایشان نوشتند که «رسولان و کشیشان و برادران، به برادران از امت‌ها که در انطاکیه و سوریه و قیلیقیه می‌باشند، سلام می‌رسانند."},{"v":24,"t":"چون شنیده شدکه بعضی از میان ما بیرون رفته، شما را به سخنان خود مشوش ساخته، دلهای شما رامنقلب می‌نمایند و می‌گویند که می‌باید مختون شده، شریعت را نگاه بدارید و ما به ایشان هیچ امر نکردیم."},{"v":25,"t":"لهذا ما به یک دل مصلحت دیدیم که چند نفر را اختیار نموده، همراه عزیزان خود برنابا و پولس به نزد شمابفرستیم،"},{"v":26,"t":"اشخاصی که جانهای خود را در راه نام خداوند ما عیسی مسیح تسلیم کرده‌اند."},{"v":27,"t":"پس یهودا و سیلاس را فرستادیم و ایشان شمارا از این امور زبانی خواهند آگاهانید."},{"v":28,"t":"زیراکه روح‌القدس و ما صواب دیدیم که باری بر شماننهیم جز این ضروریات"},{"v":29,"t":"که از قربانی های بتها و خون و حیوانات خفه شده و زنا بپرهیزید که هرگاه از این امور خود را محفوظ دارید به نیکویی خواهید پرداخت والسلام.»"},{"v":30,"t":"پس ایشان مرخص شده، به انطاکیه آمدندو جماعت را فراهم آورده، نامه را رسانیدند."},{"v":31,"t":"چون مطالعه کردند، از این تسلی شادخاطرگشتند."},{"v":32,"t":"و یهودا و سیلاس چونکه ایشان هم نبی بودند، برادران را به سخنان بسیار، نصیحت وتقویت نمودند."},{"v":33,"t":"پس چون مدتی در آنجا بسربردند به سلامتی از برادران رخصت گرفته، به سوی فرستندگان خود توجه نمودند."},{"v":34,"t":"اماپولس و برنابا در انطاکیه توقف نموده،"},{"v":35,"t":"بابسیاری دیگر تعلیم و بشارت به کلام خدامی دادند."},{"v":36,"t":"و بعد از ایام چند پولس به برنابا گفت: «برگردیم و برادران را در هر شهری که در آنها به کلام خداوند اعلام نمودیم، دیدن کنیم که چگونه می‌باشند.»"},{"v":37,"t":"اما برنابا چنان مصلحت دید که یوحنای ملقب به مرقس را همراه نیز بردارد."},{"v":38,"t":"لیکن پولس چنین صلاح دانست که شخصی راکه از پمفلیه از ایشان جدا شده بود و با ایشان درکار همراهی نکرده بود، با خود نبرد."},{"v":39,"t":"پس نزاعی سخت شد بحدی که از یکدیگر جدا شده، برنابا مرقس را برداشته، به قپرس از راه دریا رفت."},{"v":40,"t":"اما پولس سیلاس را اختیار کرد و از برادران به فیض خداوند سپرده شده، رو به سفر نهاد."},{"v":41,"t":"و ازسوریه و قیلیقیه عبور کرده، کلیساها را استوارمی نمود."}],"en":[{"v":1,"t":"Some men came down from Judea and taught the brothers, “Unless you are circumcised after the custom of Moses, you can’t be saved.”"},{"v":2,"t":"Therefore when Paul and Barnabas had no small discord and discussion with them, they appointed Paul, Barnabas, and some others of them to go up to Jerusalem to the apostles and elders about this question."},{"v":3,"t":"They, being sent on their way by the assembly, passed through both Phoenicia and Samaria, declaring the conversion of the Gentiles. They caused great joy to all the brothers."},{"v":4,"t":"When they had come to Jerusalem, they were received by the assembly and the apostles and the elders, and they reported everything that God had done with them."},{"v":5,"t":"But some of the sect of the Pharisees who believed rose up, saying, “It is necessary to circumcise them, and to command them to keep the law of Moses.”"},{"v":6,"t":"The apostles and the elders were gathered together to see about this matter."},{"v":7,"t":"When there had been much discussion, Peter rose up and said to them, “Brothers, you know that a good while ago God made a choice among you that by my mouth the nations should hear the word of the Good News and believe."},{"v":8,"t":"God, who knows the heart, testified about them, giving them the Holy Spirit, just like he did to us."},{"v":9,"t":"He made no distinction between us and them, cleansing their hearts by faith."},{"v":10,"t":"Now therefore why do you tempt God, that you should put a yoke on the neck of the disciples which neither our fathers nor we were able to bear?"},{"v":11,"t":"But we believe that we are saved through the grace of the Lord Jesus, just as they are.”"},{"v":12,"t":"All the multitude kept silence, and they listened to Barnabas and Paul reporting what signs and wonders God had done among the nations through them."},{"v":13,"t":"After they were silent, James answered, “Brothers, listen to me."},{"v":14,"t":"Simeon has reported how God first visited the nations to take out of them a people for his name."},{"v":15,"t":"This agrees with the words of the prophets. As it is written,"},{"v":16,"t":"‘After these things I will return. I will again build the tabernacle of David, which has fallen. I will again build its ruins. I will set it up"},{"v":17,"t":"that the rest of men may seek after the Lord: all the Gentiles who are called by my name, says the Lord, who does all these things.’"},{"v":18,"t":"“All of God’s works are known to him from eternity."},{"v":19,"t":"Therefore my judgment is that we don’t trouble those from among the Gentiles who turn to God,"},{"v":20,"t":"but that we write to them that they abstain from the pollution of idols, from sexual immorality, from what is strangled, and from blood."},{"v":21,"t":"For Moses from generations of old has in every city those who preach him, being read in the synagogues every Sabbath.”"},{"v":22,"t":"Then it seemed good to the apostles and the elders, with the whole assembly, to choose men out of their company, and send them to Antioch with Paul and Barnabas: Judas called Barsabbas, and Silas, chief men among the brothers."},{"v":23,"t":"They wrote these things by their hand: “The apostles, the elders, and the brothers, to the brothers who are of the Gentiles in Antioch, Syria, and Cilicia: greetings."},{"v":24,"t":"Because we have heard that some who went out from us have troubled you with words, unsettling your souls, saying, ‘You must be circumcised and keep the law,’ to whom we gave no commandment;"},{"v":25,"t":"it seemed good to us, having come to one accord, to choose out men and send them to you with our beloved Barnabas and Paul,"},{"v":26,"t":"men who have risked their lives for the name of our Lord Jesus Christ."},{"v":27,"t":"We have sent therefore Judas and Silas, who themselves will also tell you the same things by word of mouth."},{"v":28,"t":"For it seemed good to the Holy Spirit, and to us, to lay no greater burden on you than these necessary things:"},{"v":29,"t":"that you abstain from things sacrificed to idols, from blood, from things strangled, and from sexual immorality, from which if you keep yourselves, it will be well with you. Farewell.”"},{"v":30,"t":"So, when they were sent off, they came to Antioch. Having gathered the multitude together, they delivered the letter."},{"v":31,"t":"When they had read it, they rejoiced over the encouragement."},{"v":32,"t":"Judas and Silas, also being prophets themselves, encouraged the brothers with many words and strengthened them."},{"v":33,"t":"After they had spent some time there, they were dismissed in peace from the brothers to the apostles."},{"v":35,"t":"But Paul and Barnabas stayed in Antioch, teaching and preaching the word of the Lord, with many others also."},{"v":36,"t":"After some days Paul said to Barnabas, “Let’s return now and visit our brothers in every city in which we proclaimed the word of the Lord, to see how they are doing.”"},{"v":37,"t":"Barnabas planned to take John, who was called Mark, with them also."},{"v":38,"t":"But Paul didn’t think that it was a good idea to take with them someone who had withdrawn from them in Pamphylia, and didn’t go with them to do the work."},{"v":39,"t":"Then the contention grew so sharp that they separated from each other. Barnabas took Mark with him and sailed away to Cyprus,"},{"v":40,"t":"but Paul chose Silas and went out, being commended by the brothers to the grace of God."},{"v":41,"t":"He went through Syria and Cilicia, strengthening the assemblies."}],"hr":[{"v":1,"t":"Uto neki siđoše iz Judeje i počeše učiti braću: “Ako se ne obrežete po običaju Mojsijevu, ne možete se spasiti.”"},{"v":2,"t":"Kad između njih te Pavla i Barnabe nasta prepirka i raspra nemalena, odrediše da Pavao i Barnaba i još neki drugi između njih uzađu u Jeruzalem k apostolima i starješinama poradi tog pitanja."},{"v":3,"t":"Oni su dakle, ispraćeni od Crkve, prolazili kroz Feniciju i Samariju pripovijedajući o obraćenju pogana i donoseći svoj braći veliku radost."},{"v":4,"t":"Kada pak stigoše u Jeruzalem, primi ih Crkva, apostoli i starješine. Ispripovjediše što sve Bog učini po njima."},{"v":5,"t":"Onda ustanu neki od onih što iz farizejske sljedbe bijahu prigrlili vjeru pa reknu: “Treba ih obrezati i zapovjediti im da opslužuju Zakon Mojsijev.”"},{"v":6,"t":"Nato se apostoli i starješine sastanu da to razmotre."},{"v":7,"t":"Nakon duge raspre ustade Petar i reče im: “Braćo, vi znate kako me Bog od najprvih dana između vas izabra da iz mojih usta pogani čuju riječ evanđelja i uzvjeruju."},{"v":8,"t":"I Bog, Poznavatelj srdaca, posvjedoči za njih: dade im Duha Svetoga kao i nama."},{"v":9,"t":"Nikakve razlike nije pravio između nas i njih: vjerom očisti njihova srca."},{"v":10,"t":"Što dakle sada iskušavate Boga stavljajući učenicima na vrat jaram kojeg ni oci naši ni mi nismo mogli nositi?"},{"v":11,"t":"Vjerujemo, naprotiv: po milosti smo Gospodina Isusa spašeni, baš kao i oni.”"},{"v":12,"t":"Nato sve mnoštvo umuknu. Slušali su Barnabu i Pavla koji pripovjedahu kolika je znamenja i čudesa Bog po njima učinio među poganima."},{"v":13,"t":"Kad oni ušutješe, progovori Jakov: “Poslušajte me, braćo!"},{"v":14,"t":"Šimun je izložio kako se Bog već na početku pobrinu između pogana uzeti narod imenu svojemu."},{"v":15,"t":"S time su u skladu riječi Proroka. Ovako je doista pisano:"},{"v":16,"t":"Nakon toga vratit ću se i opet podići pali šator Davidov, iz ruševina ga podići, opet ga sazidati"},{"v":17,"t":"da preostali ljudi potraže Gospodina i svi pogani na koje je zazvano ime moje, govori Gospodin, koji to"},{"v":18,"t":"obznanjuje odvijeka."},{"v":19,"t":"Zato smatram da ne valja dodijavati onima koji se s poganstva obraćaju k Bogu,"},{"v":20,"t":"nego im poručiti da se uzdržavaju od mesa okaljana idolima, od bludništva, od udavljenoga i od krvi."},{"v":21,"t":"Ta Mojsije od pradavnih naraštaja ima po gradovima propovjednike koji ga u sinagogama svake subote čitaju.”"},{"v":22,"t":"Tad apostoli i starješine zajedno sa svom Crkvom zaključe izabrati neke muževe između sebe i poslati ih u Antiohiju s Pavlom i Barnabom. Bijahu to Juda zvani Barsaba, i Sila, muževi vodeći među braćom."},{"v":23,"t":"Po njima pošalju ovo pismo: “Apostoli i starješine, braća, braći iz poganstva po Antiohiji, Siriji i Ciliciji - pozdrav!”"},{"v":24,"t":"“Budući da smo čuli kako vas neki od naših, ali bez našega naloga, nekakvim izjavama smetoše i duše vam uznemiriše,"},{"v":25,"t":"zaključismo jednodušno izabrati neke muževe i poslati ih k vama zajedno s našim ljubljenim Barnabom i Pavlom,"},{"v":26,"t":"ljudima koji su svoje živote izložili za ime Gospodina našega Isusa Krista."},{"v":27,"t":"Šaljemo vam dakle Judu i Silu. Oni će vam i usmeno priopćiti to isto."},{"v":28,"t":"Zaključismo Duh Sveti i mi ne nametati vam nikakva tereta osim onoga što je potrebno:"},{"v":29,"t":"uzdržavati se od mesa žrtvovana idolima, od krvi, od udavljenoga i od bludništva. Budete li se toga držali, dobro ćete učiniti. Živjeli!”"},{"v":30,"t":"Oni su se dakle oprostili i sišli u Antiohiju; sabrali su mnoštvo i predali pismo."},{"v":31,"t":"Kad ga pročitaše, svi se obradovaše zbog ohrabrenja."},{"v":32,"t":"Juda i Sila, i sami proroci, mnogim riječima ohrabriše i utvrdiše braću."},{"v":33,"t":"Neko se vrijeme zadrže pa se onda s mirom od braće vrate onima koji ih poslaše."},{"v":34,"t":"#"},{"v":35,"t":"A Pavao i Barnaba ostadoše u Antiohiji naučavajući i navješćujući zajedno s mnogima drugima riječ Gospodnju."},{"v":36,"t":"Nakon nekog vremena reče Pavao Barnabi: “Vratimo se i pohodimo braću po svim gradovima u kojima smo navješćivali riječ Gospodnju, da vidimo kako su!”"},{"v":37,"t":"Barnaba je htio povesti i Ivana zvanog Marko."},{"v":38,"t":"Pavao pak nije smatrao uputnim sa sobom voditi onoga koji se u Pamfiliji odvojio od njih te nije s njima pošao na djelo."},{"v":39,"t":"Spopade ih takva ogorčenost da se raziđoše: Barnaba povede Marka i otplovi na Cipar,"},{"v":40,"t":"a Pavao sebi izabra Silu pa od braće povjeren milosti Gospodnjoj"},{"v":41,"t":"proputova Siriju i Ciliciju, utvrđujući Crkve."}]},"16":{"fa":[{"v":1,"t":"و به دربه و لستره آمد که اینک شاگردی تیموتاوس نام آنجا بود، پسر زن یهودیه مومنه لیکن پدرش یونانی بود."},{"v":2,"t":"که برادران در لستره و ایقونیه بر او شهادت می‌دادند."},{"v":3,"t":"چون پولس خواست او همراه وی بیاید، او راگرفته مختون ساخت، به‌سبب یهودیانی که در آن نواحی بودند زیرا که همه پدرش را می‌شناختندکه یونانی بود."},{"v":4,"t":"و در هر شهری که می‌گشتند، قانونها را که رسولان و کشیشان در اورشلیم حکم فرموده بودند، بدیشان می‌سپردند تا حفظ نمایند."},{"v":5,"t":"پس کلیساها در ایمان استوار می‌شدند و روزبروز در شماره افزوده می‌گشتند."},{"v":6,"t":"و چون از فریجیه و دیار غلاطیه عبورکردند، روح‌القدس ایشان را از رسانیدن کلام به آسیا منع نمود."},{"v":7,"t":"پس به میسیا آمده، سعی نمودندکه به بطینیا بروند، لیکن روح عیسی ایشان رااجازت نداد."},{"v":8,"t":"و از میسیا گذشته به ترواس رسیدند."},{"v":9,"t":"شبی پولس را رویایی رخ نمود که شخصی از اهل مکادونیه ایستاده بود التماس نموده گفت: «به مکادونیه آمده، ما را امداد فرما.»"},{"v":10,"t":"چون این‌رویا را دید، بی‌درنگ عازم سفرمکادونیه شدیم، زیرا به یقین دانستیم که خداوندما را خوانده است تا بشارت بدیشان رسانیم."},{"v":11,"t":"پس از ترواس به کشتی نشسته، به راه مستقیم به ساموتراکی رفتیم و روز دیگر به نیاپولیس."},{"v":12,"t":"و از آنجا به فیلپی رفتیم که شهر اول ازسرحد مکادونیه و کلونیه است و در آن شهر‌چندروز توقف نمودیم."},{"v":13,"t":"و در روز سبت از شهربیرون شده و به کنار رودخانه جایی که نماز می گذاردند، نشسته با زنانی که در آنجا جمع می‌شدند سخن راندیم."},{"v":14,"t":"و زنی لیدیه نام، ارغوان فروش، که از شهر طیاتیرا و خداپرست بود، می‌شنید که خداوند دل او را گشود تا سخنان پولس را بشنود."},{"v":15,"t":"و چون او و اهل خانه‌اش تعمید یافتند، خواهش نموده، گفت: «اگر شما رایقین است که به خداوند ایمان آوردم، به خانه من درآمده، بمانید.» و ما را الحاح نمود."},{"v":16,"t":"و واقع شد که چون ما به محل نمازمی رفتیم، کنیزی که روح تفال داشت و ازغیب گویی منافع بسیار برای آقایان خود پیدامی نمود، به ما برخورد."},{"v":17,"t":"و از عقب پولس و ماآمده، ندا کرده، می‌گفت که «این مردمان خدام خدای تعالی می‌باشند که شما را از طریق نجات اعلام می‌نمایند.»"},{"v":18,"t":"و چون این کار را روزهای بسیار می‌کرد، پولس دلتنگ شده، برگشت و به روح گفت: «تو را می‌فرمایم به نام عیسی مسیح ازاین دختر بیرون بیا.» که در ساعت از او بیرون شد."},{"v":19,"t":"اما چون آقایانش دیدند که از کسب خودمایوس شدند، پولس و سیلاس را گرفته، در بازارنزد حکام کشیدند."},{"v":20,"t":"و ایشان را نزد والیان حاضرساخته، گفتند: «این دو شخص شهر ما را به شورش آورده‌اند و از یهود هستند،"},{"v":21,"t":"و رسومی را اعلام می‌نمایند که پذیرفتن و به‌جا آوردن آنهابر ما که رومیان هستیم، جایز نیست.»"},{"v":22,"t":"پس خلق بر ایشان هجوم آوردند و والیان جامه های ایشان را کنده، فرمودند ایشان را چوب بزنند."},{"v":23,"t":"و چون ایشان را چوب بسیار زدند، به زندان افکندند و داروغه زندان را تاکید فرمودند که ایشان را محکم نگاه دارد."},{"v":24,"t":"و چون او بدینطورامر یافت، ایشان را به زندان درونی انداخت وپایهای ایشان را در کنده مضبوط کرد."},{"v":25,"t":"اما قریب به نصف شب، پولس و سیلاس دعا کرده، خدا را تسبیح می‌خواندند و زندانیان ایشان را می‌شنیدند."},{"v":26,"t":"که ناگاه زلزله‌ای عظیم حادث گشت بحدی که بیناد زندان به جنبش درآمد و دفعه همه درها باز شد و زنجیرها از همه فرو ریخت."},{"v":27,"t":"اما داروغه بیدار شده، چون درهای زندان را گشوده دید، شمشیر خود راکشیده، خواست خود را بکشد زیرا گمان برد که زندانیان فرار کرده‌اند."},{"v":28,"t":"اما پولس به آواز بلندصدا زده، گفت: «خود را ضرری مرسان زیرا که ماهمه در اینجا هستیم.»"},{"v":29,"t":"پس چراغ طلب نموده، به اندرون جست و لرزان شده، نزد پولس وسیلاس افتاد."},{"v":30,"t":"و ایشان را بیرون آورده، گفت: «ای آقایان، مرا چه باید کرد تا نجات یابم؟»"},{"v":31,"t":"گفتند: «به خداوند عیسی مسیح ایمان آور که تو و اهل خانه ات نجات خواهید یافت.»"},{"v":32,"t":"آنگاه کلام خداوند را برای او وتمامی اهل بیتش بیان کردند."},{"v":33,"t":"پس ایشان را برداشته، در همان ساعت شب زخمهای ایشان را شست و خود و همه کسانش فی الفور تعمید یافتند."},{"v":34,"t":"و ایشان را به خانه خود درآورده، خوانی پیش ایشان نهاد و باتمامی عیال خود به خدا ایمان آورده، شادگردیدند."},{"v":35,"t":"اما چون روز شد، والیان فراشان فرستاده، گفتند: «آن دو شخص را رها نما.»"},{"v":36,"t":"آنگاه داروغه پولس را از این سخنان آگاهانیدکه «والیان فرستاده‌اند تا رستگار شوید. پس الان بیرون آمده، به سلامتی روانه شوید.»"},{"v":37,"t":"لیکن پولس بدیشان گفت: «ما را که مردمان رومی می‌باشیم، آشکارا و بی‌حجت زده، به زندان انداختند. آیا الان ما را به پنهانی بیرون می‌نمایند؟ نی بلکه خود آمده، ما را بیرون بیاورند."},{"v":38,"t":"پس فراشان این سخنان را به والیان گفتند و چون شنیدند که رومی هستند بترسیدند"},{"v":39,"t":"و آمده، بدیشان التماس نموده، بیرون آوردندو خواهش کردند که از شهر بروند."},{"v":40,"t":"آنگاه اززندان بیرون آمده، به خانه لیدیه شتافتند و بابرادران ملاقات نموده و ایشان را نصیحت کرده، روانه شدند."}],"en":[{"v":1,"t":"He came to Derbe and Lystra; and behold, a certain disciple was there, named Timothy, the son of a Jewess who believed, but his father was a Greek."},{"v":2,"t":"The brothers who were at Lystra and Iconium gave a good testimony about him."},{"v":3,"t":"Paul wanted to have him go out with him, and he took and circumcised him because of the Jews who were in those parts, for they all knew that his father was a Greek."},{"v":4,"t":"As they went on their way through the cities, they delivered the decrees to them to keep which had been ordained by the apostles and elders who were at Jerusalem."},{"v":5,"t":"So the assemblies were strengthened in the faith, and increased in number daily."},{"v":6,"t":"When they had gone through the region of Phrygia and Galatia, they were forbidden by the Holy Spirit to speak the word in Asia."},{"v":7,"t":"When they had come opposite Mysia, they tried to go into Bithynia, but the Spirit didn’t allow them."},{"v":8,"t":"Passing by Mysia, they came down to Troas."},{"v":9,"t":"A vision appeared to Paul in the night. There was a man of Macedonia standing, begging him and saying, “Come over into Macedonia and help us.”"},{"v":10,"t":"When he had seen the vision, immediately we sought to go out to Macedonia, concluding that the Lord had called us to preach the Good News to them."},{"v":11,"t":"Setting sail therefore from Troas, we made a straight course to Samothrace, and the day following to Neapolis;"},{"v":12,"t":"and from there to Philippi, which is a city of Macedonia, the foremost of the district, a Roman colony. We were staying some days in this city."},{"v":13,"t":"On the Sabbath day we went outside of the city by a riverside, where we supposed there was a place of prayer, and we sat down and spoke to the women who had come together."},{"v":14,"t":"A certain woman named Lydia, a seller of purple, of the city of Thyatira, one who worshiped God, heard us. The Lord opened her heart to listen to the things which were spoken by Paul."},{"v":15,"t":"When she and her household were baptized, she begged us, saying, “If you have judged me to be faithful to the Lord, come into my house and stay.” So she persuaded us."},{"v":16,"t":"As we were going to prayer, a certain girl having a spirit of divination met us, who brought her masters much gain by fortune telling."},{"v":17,"t":"Following Paul and us, she cried out, “These men are servants of the Most High God, who proclaim to us a way of salvation!”"},{"v":18,"t":"She was doing this for many days. But Paul, becoming greatly annoyed, turned and said to the spirit, “I command you in the name of Jesus Christ to come out of her!” It came out that very hour."},{"v":19,"t":"But when her masters saw that the hope of their gain was gone, they seized Paul and Silas and dragged them into the marketplace before the rulers."},{"v":20,"t":"When they had brought them to the magistrates, they said, “These men, being Jews, are agitating our city"},{"v":21,"t":"and advocate customs which it is not lawful for us to accept or to observe, being Romans.”"},{"v":22,"t":"The multitude rose up together against them and the magistrates tore their clothes from them, then commanded them to be beaten with rods."},{"v":23,"t":"When they had laid many stripes on them, they threw them into prison, charging the jailer to keep them safely."},{"v":24,"t":"Having received such a command, he threw them into the inner prison and secured their feet in the stocks."},{"v":25,"t":"But about midnight Paul and Silas were praying and singing hymns to God, and the prisoners were listening to them."},{"v":26,"t":"Suddenly there was a great earthquake, so that the foundations of the prison were shaken; and immediately all the doors were opened, and everyone’s bonds were loosened."},{"v":27,"t":"The jailer, being roused out of sleep and seeing the prison doors open, drew his sword and was about to kill himself, supposing that the prisoners had escaped."},{"v":28,"t":"But Paul cried with a loud voice, saying, “Don’t harm yourself, for we are all here!”"},{"v":29,"t":"He called for lights, sprang in, fell down trembling before Paul and Silas,"},{"v":30,"t":"brought them out, and said, “Sirs, what must I do to be saved?”"},{"v":31,"t":"They said, “Believe in the Lord Jesus Christ, and you will be saved, you and your household.”"},{"v":32,"t":"They spoke the word of the Lord to him, and to all who were in his house."},{"v":33,"t":"He took them the same hour of the night and washed their stripes, and was immediately baptized, he and all his household."},{"v":34,"t":"He brought them up into his house and set food before them, and rejoiced greatly with all his household, having believed in God."},{"v":35,"t":"But when it was day, the magistrates sent the sergeants, saying, “Let those men go.”"},{"v":36,"t":"The jailer reported these words to Paul, saying, “The magistrates have sent to let you go; now therefore come out and go in peace.”"},{"v":37,"t":"But Paul said to them, “They have beaten us publicly without a trial, men who are Romans, and have cast us into prison! Do they now release us secretly? No, most certainly, but let them come themselves and bring us out!”"},{"v":38,"t":"The sergeants reported these words to the magistrates, and they were afraid when they heard that they were Romans,"},{"v":39,"t":"and they came and begged them. When they had brought them out, they asked them to depart from the city."},{"v":40,"t":"They went out of the prison and entered into Lydia’s house. When they had seen the brothers, they encouraged them, then departed."}],"hr":[{"v":1,"t":"Stiže tako u Derbu i Listru. Ondje, gle, bijaše učenik neki imenom Timotej, sin neke pokrštene Židovke i oca Grka."},{"v":2,"t":"Uživao je dobar glas među braćom u Listri i Ikoniju."},{"v":3,"t":"Pavao htjede da on pođe s njime pa ga uze i obreza zbog Židova koji bijahu u onim mjestima. Jer svi su znali da mu je otac Grk."},{"v":4,"t":"I kako su prolazili gradovima, predavali su im za opsluživanje odredbe koje su apostoli i starješine utvrdili u Jeruzalemu."},{"v":5,"t":"Tako se Crkve učvršćivahu u vjeri i broj im se danomice povećavao."},{"v":6,"t":"Prođoše Frigiju i galacijski kraj jer ih je Duh Sveti spriječio propovijedati riječ u Aziji."},{"v":7,"t":"Kad su došli do Mizije, htjedoše u Bitiniju, ali im ne dopusti Duh Isusov."},{"v":8,"t":"Onda prođoše Miziju i siđoše u Troadu."},{"v":9,"t":"Noću je Pavao imao viđenje: Makedonac neki stajaše i zaklinjaše ga: “Prijeđi u Makedoniju i pomozi nam!”"},{"v":10,"t":"Nakon viđenja nastojasmo odmah otputovati u Makedoniju, uvjereni da nas Bog zove navješćivati im evanđelje."},{"v":11,"t":"Otplovismo iz Troade i zaputismo se ravno u Samotraku pa sutradan u Neapol,"},{"v":12,"t":"a odande u naseobinu Filipe - grad prvog dijela Makedonije. U tom se gradu zadržasmo nekoliko dana."},{"v":13,"t":"U dan subotni iziđosmo izvan gradskih vrata k rijeci, gdje smo mislili da će biti bogomolja. Sjedosmo i stadosmo govoriti okupljenim ženama."},{"v":14,"t":"Slušala je tako i neka bogobojazna žena imenom Lidija, prodavačica grimiza iz grada Tijatire. Gospodin joj otvori srce, te ona prihvati što je Pavao govorio."},{"v":15,"t":"Pošto se pak krsti ona i njezin dom, zamoli: “Ako smatrate da sam vjerna Gospodinu, uđite u moj dom i ostanite u njemu.” I prisili nas."},{"v":16,"t":"Jednom nas na putu u bogomolju sretne neka ropkinja koja je imala duha vračarskoga i gatajući donosila veliku dobit svojim gospodarima."},{"v":17,"t":"Pošla je za Pavlom i za nama te vikala: “Ovi su ljudi sluge Boga Svevišnjega; navješćuju vam put spasenja.”"},{"v":18,"t":"To je činila mnogo dana. Pavlu to napokon dodija pa se okrenu i reče duhu: “Zapovijedam ti u ime Isusa Krista: iziđi iz nje!” I iziđe toga časa."},{"v":19,"t":"Kad njezini gospodari vidješe da im nesta nade u dobit, pograbiše Pavla i Silu te ih odvukoše na trg pred glavare."},{"v":20,"t":"Privedoše ih pretorima i rekoše: “Ovi ljudi uznemiruju naš grad. Židovi su"},{"v":21,"t":"te šire običaje kojih mi Rimljani ne smijemo ni prihvatiti ni držati.”"},{"v":22,"t":"Nato svjetina nahrupi na njih, a pretori trgoše s njih odijelo i zapovjediše da se išibaju."},{"v":23,"t":"Pošto ih izudaraše, bace ih u tamnicu i zapovjede tamničaru da ih pomno čuva."},{"v":24,"t":"Primivši takvu zapovijed, uze ih on i baci u nutarnju tamnicu, a noge im stavi u klade."},{"v":25,"t":"Oko ponoći su Pavao i Sila molili pjevajući hvalu Bogu, a uznici ih slušali."},{"v":26,"t":"Odjednom nasta potres velik te se poljuljaše temelji zatvora, umah se otvoriše sva vrata, i svima spadoše okovi."},{"v":27,"t":"Tamničar se prenu oda sna pa kad ugleda tamnička vrata otvorena, trgnu mač i samo što se ne ubi misleći da su uznici pobjegli."},{"v":28,"t":"Ali Pavao povika iza glasa: “Ne čini sebi nikakva zla! Svi smo ovdje!”"},{"v":29,"t":"Onaj nato zaiska svjetlo, uleti i dršćući baci se pred Pavla i Silu;"},{"v":30,"t":"izvede ih i upita: “Gospodo, što mi je činiti da se spasim?”"},{"v":31,"t":"Oni će mu: “Vjeruj u Gospodina Isusa i spasit ćeš se - ti i dom tvoj!”"},{"v":32,"t":"Onda navijestiše riječ Gospodnju njemu i svima u domu njegovu."},{"v":33,"t":"Te iste noćne ure uze ih, opra im rane pa se odmah krsti - on i svi njegovi."},{"v":34,"t":"Onda ih uvede u dom, prostre stol te se zajedno sa svim domom obradova što je povjerovao Bogu."},{"v":35,"t":"Kad se razdani, poslaše pretori liktore s porukom: “Pusti te ljude!”"},{"v":36,"t":"Tamničar to priopći Pavlu: “Pretori, reče, poručiše da vas pustim. Iziđite dakle sad i pođite u miru!”"},{"v":37,"t":"Nato im Pavao odvrati: “Javno su nas neosuđene išibali, nas rimske građane, i bacili u tamnicu. A sada da nas potajno izbace? Nipošto, nego neka oni sami dođu i izvedu nas!”"},{"v":38,"t":"Liktori to jave pretorima. Oni su se uplašili kada doznaše da su Rimljani."},{"v":39,"t":"Zato dođu da ih nagovore pa ih izvedu i zamole da odu iz grada."},{"v":40,"t":"Izišavši iz tamnice, oni pođu k Lidiji, pogledaju i obodre braću pa odu."}]},"17":{"fa":[{"v":1,"t":"و از امفپولس و اپلونیه گذشته، به تسالونیکی رسیدند که در آنجا کنیسه یهود بود."},{"v":2,"t":"پس پولس برحسب عادت خود، نزدایشان داخل شده، در سه سبت با ایشان از کتاب مباحثه می‌کرد"},{"v":3,"t":"و واضح و مبین می‌ساخت که «لازم بود مسیح زحمت بیند و از مردگان برخیزدو عیسی که خبر او را به شما می‌دهم، این مسیح است.»"},{"v":4,"t":"و بعضی از ایشان قبول کردند و با پولس و سیلاس متحد شدند و از یونانیان خداترس، گروهی عظیم و از زنان شریف، عددی کثیر."},{"v":5,"t":"امایهودیان بی‌ایمان حسد برده، چند نفر اشرار ازبازاریها را برداشته، خلق را جمع کرده، شهر را به شورش آوردند و به خانه یاسون تاخته، خواستندایشان را در میان مردم ببرند."},{"v":6,"t":"و چون ایشان رانیافتند، یاسون و چند برادر را نزد حکام شهرکشیدند و ندا می‌کردند که «آنانی که ربع مسکون را شورانیده‌اند، حال بدینجا نیزآمده‌اند."},{"v":7,"t":"و یاسون ایشان را پذیرفته است وهمه اینها برخلاف احکام قیصر عمل می‌کنند وقایل بر این هستند که پادشاهی دیگر هست یعنی عیسی.»"},{"v":8,"t":"پس خلق و حکام شهر را ازشنیدن این سخنان مضطرب ساختند"},{"v":9,"t":"و ازیاسون و دیگران کفالت گرفته، ایشان را رهاکردند."},{"v":10,"t":"اما برادران بی‌درنگ در شب پولس وسیلاس را به سوی بیریه روانه کردند و ایشان بدانجا رسیده، به کنیسه یهود درآمدند."},{"v":11,"t":"و اینهااز اهل تسالونیکی نجیب‌تر بودند، چونکه درکمال رضامندی کلام را پذیرفتند و هر روز کتب را تفتیش می‌نمودند که آیا این همچنین است."},{"v":12,"t":"پس بسیاری از ایشان ایمان آوردند و از زنان شریف یونانیه و از مردان، جمعی عظیم."},{"v":13,"t":"لیکن چون یهودیان تسالونیکی فهمیدند که پولس در بیریه نیز به کلام خدا موعظه می‌کند، درآنجا هم رفته، خلق را شورانیدند."},{"v":14,"t":"در ساعت برادران پولس را به سوی دریا روانه کردند ولی سیلاس با تیموتاوس در آنجا توقف نمودند."},{"v":15,"t":"ورهنمایان پولس او را به اطینا آوردند و حکم برای سیلاس و تیموتاوس گرفته که به زودی هر‌چه تمام تر به نزد او آیند، روانه شدند."},{"v":16,"t":"اما چون پولس در اطینا انتظار ایشان رامی کشید، روح او در اندرونش مضطرب گشت چون دید که شهر از بتها پر است."},{"v":17,"t":"پس درکنیسه با یهودیان و خداپرستان و در بازار، هرروزه با هر‌که ملاقات می‌کرد، مباحثه می‌نمود."},{"v":18,"t":"اما بعضی از فلاسفه اپیکوریین و رواقیین با اوروبرو شده، بعضی می‌گفتند: «این یاوه‌گو چه می‌خواهد بگوید؟» و دیگران گفتند: «ظاهر واعظ به خدایان غریب است.» زیرا که ایشان را به عیسی و قیامت بشارت می‌داد."},{"v":19,"t":"پس او راگرفته، به کوه مریخ بردند و گفتند: «آیا می‌توانیم یافت که این تعلیم تازه‌ای که تو می‌گویی چیست؟"},{"v":20,"t":"چونکه سخنان غریب به گوش مامی رسانی. پس می‌خواهیم بدانیم از اینها چه مقصود است.»"},{"v":21,"t":"اما جمیع اهل اطینا و غربای ساکن آنجا جز برای گفت و شنید درباره چیزهای تازه فراغتی نمی داشتند."},{"v":22,"t":"پس پولس در وسط کوه مریخ ایستاده، گفت: «ای مردان اطینا، شما را از هر جهت بسیاردیندار یافته‌ام،"},{"v":23,"t":"زیرا چون سیر کرده، معابدشما را نظاره می‌نمودم، مذبحی یافتم که بر آن، نام خدای ناشناخته نوشته بود. پس آنچه را شماناشناخته می‌پرستید، من به شما اعلام می‌نمایم."},{"v":24,"t":"خدایی که جهان و آنچه در آن است آفرید، چونکه او مالک آسمان و زمین است، درهیکلهای ساخته شده به‌دستها ساکن نمی باشد"},{"v":25,"t":"و از دست مردم خدمت کرده نمی شود که گویامحتاج چیزی باشد، بلکه خود به همگان حیات ونفس و جمیع چیزها می‌بخشد."},{"v":26,"t":"و هر امت انسان را از یک خون ساخت تا بر تمامی روی زمین مسکن گیرند و زمانهای معین و حدودمسکنهای ایشان را مقرر فرمود"},{"v":27,"t":"تا خدا را طلب کنند که شاید او را تفحص کرده، بیابند، با آنکه ازهیچ‌یکی از ما دور نیست."},{"v":28,"t":"زیرا که در او زندگی و حرکت و وجود داریم چنانکه بعضی از شعرای شما نیز گفته‌اند که از نسل او می‌باشیم."},{"v":29,"t":"پس چون از نسل خدا می‌باشیم، نشاید گمان برد که الوهیت شباهت دارد به طلا یا نقره یا سنگ منقوش به صنعت یا مهارت انسان."},{"v":30,"t":"پس خدا اززمانهای جهالت چشم پوشیده، الان تمام خلق رادر هر جا حکم می‌فرماید که توبه کنند."},{"v":31,"t":"زیرا روزی را مقرر فرمود که در آن ربع مسکون را به انصاف داوری خواهد نمود به آن مردی که معین فرمود و همه را دلیل داد به اینکه او را از مردگان برخیزانید.»"},{"v":32,"t":"چون ذکر قیامت مردگان شنیدند، بعضی استهزا نمودند و بعضی گفتند مرتبه دیگر در این امر از تو خواهیم شنید."},{"v":33,"t":"و همچنین پولس ازمیان ایشان بیرون رفت."},{"v":34,"t":"لیکن چند نفر بدوپیوسته ایمان آوردند که از‌جمله ایشان دیونیسیوس آریوپاغی بود و زنی که دامرس نام داشت و بعضی دیگر با ایشان."}],"en":[{"v":1,"t":"Now when they had passed through Amphipolis and Apollonia, they came to Thessalonica, where there was a Jewish synagogue."},{"v":2,"t":"Paul, as was his custom, went in to them; and for three Sabbath days reasoned with them from the Scriptures,"},{"v":3,"t":"explaining and demonstrating that the Christ had to suffer and rise again from the dead, and saying, “This Jesus, whom I proclaim to you, is the Christ.”"},{"v":4,"t":"Some of them were persuaded and joined Paul and Silas: of the devout Greeks a great multitude, and not a few of the chief women."},{"v":5,"t":"But the unpersuaded Jews took along some wicked men from the marketplace and gathering a crowd, set the city in an uproar. Assaulting the house of Jason, they sought to bring them out to the people."},{"v":6,"t":"When they didn’t find them, they dragged Jason and certain brothers before the rulers of the city, crying, “These who have turned the world upside down have come here also,"},{"v":7,"t":"whom Jason has received. These all act contrary to the decrees of Caesar, saying that there is another king, Jesus!”"},{"v":8,"t":"The multitude and the rulers of the city were troubled when they heard these things."},{"v":9,"t":"When they had taken security from Jason and the rest, they let them go."},{"v":10,"t":"The brothers immediately sent Paul and Silas away by night to Beroea. When they arrived, they went into the Jewish synagogue."},{"v":11,"t":"Now these were more noble than those in Thessalonica, in that they received the word with all readiness of mind, examining the Scriptures daily to see whether these things were so."},{"v":12,"t":"Many of them therefore believed; also of the prominent Greek women, and not a few men."},{"v":13,"t":"But when the Jews of Thessalonica had knowledge that the word of God was proclaimed by Paul at Beroea also, they came there likewise, agitating the multitudes."},{"v":14,"t":"Then the brothers immediately sent out Paul to go as far as to the sea, and Silas and Timothy still stayed there."},{"v":15,"t":"But those who escorted Paul brought him as far as Athens. Receiving a commandment to Silas and Timothy that they should come to him very quickly, they departed."},{"v":16,"t":"Now while Paul waited for them at Athens, his spirit was provoked within him as he saw the city full of idols."},{"v":17,"t":"So he reasoned in the synagogue with the Jews and the devout persons, and in the marketplace every day with those who met him."},{"v":18,"t":"Some of the Epicurean and Stoic philosophers also were conversing with him. Some said, “What does this babbler want to say?” Others said, “He seems to be advocating foreign deities,” because he preached Jesus and the resurrection."},{"v":19,"t":"They took hold of him and brought him to the Areopagus, saying, “May we know what this new teaching is, which you are speaking about?"},{"v":20,"t":"For you bring certain strange things to our ears. We want to know therefore what these things mean.”"},{"v":21,"t":"Now all the Athenians and the strangers living there spent their time in nothing else, but either to tell or to hear some new thing."},{"v":22,"t":"Paul stood in the middle of the Areopagus and said, “You men of Athens, I perceive that you are very religious in all things."},{"v":23,"t":"For as I passed along and observed the objects of your worship, I also found an altar with this inscription: ‘TO AN UNKNOWN GOD.’ What therefore you worship in ignorance, I announce to you."},{"v":24,"t":"The God who made the world and all things in it, he, being Lord of heaven and earth, doesn’t dwell in temples made with hands."},{"v":25,"t":"He isn’t served by men’s hands, as though he needed anything, seeing he himself gives to all life and breath and all things."},{"v":26,"t":"He made from one blood every nation of men to dwell on all the surface of the earth, having determined appointed seasons and the boundaries of their dwellings,"},{"v":27,"t":"that they should seek the Lord, if perhaps they might reach out for him and find him, though he is not far from each one of us."},{"v":28,"t":"‘For in him we live, move, and have our being.’ As some of your own poets have said, ‘For we are also his offspring.’"},{"v":29,"t":"Being then the offspring of God, we ought not to think that the Divine Nature is like gold, or silver, or stone, engraved by art and design of man."},{"v":30,"t":"The times of ignorance therefore God overlooked. But now he commands that all people everywhere should repent,"},{"v":31,"t":"because he has appointed a day in which he will judge the world in righteousness by the man whom he has ordained; of which he has given assurance to all men, in that he has raised him from the dead.”"},{"v":32,"t":"Now when they heard of the resurrection of the dead, some mocked; but others said, “We want to hear you again concerning this.”"},{"v":33,"t":"Thus Paul went out from among them."},{"v":34,"t":"But certain men joined with him and believed, including Dionysius the Areopagite, and a woman named Damaris, and others with them."}],"hr":[{"v":1,"t":"Prošavši kroz Amfipol i Apoloniju, stigoše u Solun, gdje bijaše židovska sinagoga."},{"v":2,"t":"Po običaju uđe Pavao onamo. Tri je subote s njima raspravljao na temelju Pisama."},{"v":3,"t":"Tumačio je i izlagao: “Trebalo je da Krist trpi i uskrsne od mrtvih. Taj Krist jest Isus koga vam ja navješćujem.”"},{"v":4,"t":"Neki se od njih uvjeriše pa se pridružiše Pavlu i Sili; tako i veliko mnoštvo bogobojaznih Grka i nemalo uglednih žena."},{"v":5,"t":"Židove nato spopade zavist pa pridobiše neke opake uličnjake, potakoše ih i pobuniše grad te nahrupiše u kuću Jasonovu tražeći da se Pavao i Sila izvedu pred narod."},{"v":6,"t":"Kako ih ne nađoše, odvukoše Jasona i neke od braće pred gradske glavare vičući: “Evo i ovdje onih koji pobuniše sav svijet."},{"v":7,"t":"Jason ih je ugostio. Svi oni rade protiv carskih odredaba: tvrde da postoji drugi kralj - Isus.”"},{"v":8,"t":"Time uzbuniše svjetinu i glavare koji su to čuli"},{"v":9,"t":"te oni od Jasona i ostalih uzeše jamčevinu pa ih pustiše."},{"v":10,"t":"Braća su pak brže-bolje noću odaslala Pavla i Silu u Bereju. Kad su stigli, odoše u židovsku sinagogu."},{"v":11,"t":"Ovi su Židovi bili plemenitiji od solunskih: primili su Riječ sa svom spremnošću i danomice istraživali Pisma, da li je to tako."},{"v":12,"t":"Mnogi od njih stoga povjerovaše, a tako i nemalo uglednih grčkih žena i muževa."},{"v":13,"t":"Ali kad su solunski Židovi doznali da Pavao i u Bereji navješćuje riječ Božju, odoše te i ondje podjariše i uzbuniše svjetinu."},{"v":14,"t":"Braća tada brže-bolje uputiše Pavla k moru. Sila pak i Timotej ostadoše ondje."},{"v":15,"t":"Pratioci dovedoše Pavla do Atene pa se vratiše noseći Sili i Timoteju zapovijed da što prije dođu k njemu."},{"v":16,"t":"Dok ih je u Ateni iščekivao, ogorči se Pavao u duši promatrajući kako je grad pokumiren."},{"v":17,"t":"Međutim raspravljaše u sinagogi sa Židovima i bogobojaznima, a na trgu svaki dan s onima koji bi se ondje zatekli."},{"v":18,"t":"Dobacivahu mu i neki od epikurejskih i stoičkih filozofa. Jedni su govorili: “Što bi htjela reći ta čavka?” Drugi pak: “Navješćuje, čini se, neke tuđe bogove.” Jer navješćivaše Isusa i uskrsnuće."},{"v":19,"t":"Onda su ga uzeli i odveli na Areopag i upitali: “Bismo li mogli znati kakav to nov nauk naučavaš?"},{"v":20,"t":"Čudnovatim nam nekim tvrdnjama uši puniš. Željeli bismo stoga znati što bi to imalo biti.”"},{"v":21,"t":"Nijedan Atenjanin ni doseljeni stranac ni na što drugo ne trati vrijeme nego na pripovijedanje i slušanje novosti."},{"v":22,"t":"Tada Pavao stade posred Areopaga i reče: “Atenjani! U svemu ste, vidim, nekako veoma bogoljubni."},{"v":23,"t":"Doista, prolazeći i promatrajući vaše svetinje nađoh i žrtvenik s natpisom: Nepoznatom Bogu. Što dakle ne poznajete, a štujete, to vam ja navješćujem.”"},{"v":24,"t":"“Bog koji stvori svijet i sve na njemu, on, neba i zemlje Gospodar, ne prebiva u rukotvorenim hramovima;"},{"v":25,"t":"i ne poslužuju ga ljudske ruke, kao da bi što trebao, on koji svima daje život, dah i - sve."},{"v":26,"t":"Od jednoga sazda cijeli ljudski rod da prebiva po svem licu zemlje; ustanovi određena vremena i međe prebivanja njihova"},{"v":27,"t":"da traže Boga, ne bi li ga kako napipali i našli. Ta nije daleko ni od koga od nas."},{"v":28,"t":"U njemu doista živimo, mičemo se i jesmo, kao što i neki od vaših pjesnika rekoše: “Njegov smo čak i rod!”"},{"v":29,"t":"“Ako smo dakle rod Božji, ne smijemo smatrati da je božanstvo slično zlatu, srebru ili kamenu, liku isklesanu umijećem i maštom ljudskom.”"},{"v":30,"t":"“I ne obazirući se na vremena neznanja, nutka sada Bog ljude da se svi i posvuda obrate"},{"v":31,"t":"jer ustanovi Dan u koji će suditi svijetu po pravdi, po Čovjeku kojega odredi, pred svima ovjerovi uskrisivši ga od mrtvih.”"},{"v":32,"t":"Kad čuše “uskrsnuće od mrtvih”, jedni se stadoše rugati, a drugi rekoše: “Još ćemo te o tom slušati!”"},{"v":33,"t":"Tako se Pavao povuče od njih."},{"v":34,"t":"Neki ipak prionuše uza nj i povjerovaše; među njima i Dionizije Areopagit, neka žena imenom Damara i drugi s njima."}]},"18":{"fa":[{"v":1,"t":"و بعد از آن پولس از اطینا روانه شده، به قرنتس آمد."},{"v":2,"t":"و مرد یهودی اکیلا نام راکه مولدش پنطس بود و از ایطالیا تازه رسیده بودو زنش پرسکله را یافت زیرا کلودیوس فرمان داده بود که همه یهودیان از روم بروند. پس نزدایشان آمد."},{"v":3,"t":"و چونکه با ایشان همپیشه بود، نزدایشان مانده، به‌کار مشغول شد و کسب ایشان خیمه‌دوزی بود."},{"v":4,"t":"و هر سبت در کنیسه مکالمه کرده، یهودیان و یونانیان را مجاب می‌ساخت."},{"v":5,"t":"اما چون سیلاس و تیموتاوس از مکادونیه آمدند، پولس در روح مجبور شده، برای یهودیان شهادت می‌داد که عیسی، مسیح است."},{"v":6,"t":"ولی چون ایشان مخالفت نموده، کفر می‌گفتند، دامن خود را بر ایشان افشانده، گفت: «خون شما بر سرشما است. من بری هستم. بعد از این به نزد امت هامی روم.»"},{"v":7,"t":"پس از آنجا نقل کرده، به خانه شخصی یوستس نام خداپرست آمد که خانه او متصل به کنیسه بود."},{"v":8,"t":"اما کرسپس، رئیس کنیسه با تمامی اهل بیتش به خداوند ایمان آوردند و بسیاری ازاهل قرنتس چون شنیدند، ایمان آورده، تعمیدیافتند."},{"v":9,"t":"شبی خداوند در رویا به پولس گفت: «ترسان مباش، بلکه سخن بگو و خاموش مباش"},{"v":10,"t":"زیرا که من با تو هستم و هیچ‌کس تو را اذیت نخواهد رسانید زیرا که مرا در این شهر خلق بسیار است.»"},{"v":11,"t":"پس مدت یک سال و شش ماه توقف نموده، ایشان را به کلام خدا تعلیم می‌داد."},{"v":12,"t":"اماچون غالیون والی اخائیه بود، یهودیان یکدل شده، بر سر پولس تاخته، او را پیش مسند حاکم بردند"},{"v":13,"t":"و گفتند: «این شخص مردم را اغوامی کند که خدا را برخلاف شریعت عبادت کنند.»"},{"v":14,"t":"چون پولس خواست حرف زند، غالیون گفت: «ای یهودیان اگر ظلمی یا فسقی فاحش می‌بود، هر آینه شرط عقل می‌بود که متحمل شما بشوم."},{"v":15,"t":"ولی چون مساله‌ای است درباره سخنان ونامها و شریعت شما، پس خود بفهمید. من درچنین امور نمی خواهم داوری کنم.»"},{"v":16,"t":"پس ایشان را از پیش مسند براند."},{"v":17,"t":"و همه سوستانیس رئیس کنسیه را گرفته او را در مقابل مسند والی بزدند و غالیون را از این امور هیچ پروانبود."},{"v":18,"t":"اما پولس بعد از آن روزهای بسیار در آنجاتوقف نمود پس برادران را وداع نموده، به سوریه از راه دریا رفت و پرسکله و اکیلا همراه او رفتند. و درکنخریه موی خود را چید چونکه نذر کرده بود."},{"v":19,"t":"و چون به افسس رسید آن دو نفر را درآنجا رها کرده، خود به کنیسه درآمده، با یهودیان مباحثه نمود."},{"v":20,"t":"و چون ایشان خواهش نمودندکه مدتی با ایشان بماند، قبول نکرد"},{"v":21,"t":"بلکه ایشان را وداع کرده، گفت که «مرا به هر صورت باید عیدآینده را در اورشلیم صرف کنم. لیکن اگر خدابخواهد، باز به نزد شما خواهم برگشت.» پس ازافسس روانه شد."},{"v":22,"t":"و به قیصریه فرود آمده (به اورشلیم ) رفت و کلیسا را تحیت نموده، به انطاکیه آمد."},{"v":23,"t":"و مدتی در آنجا مانده، باز به سفر توجه نمود و در ملک غلاطیه و فریجیه جابجا می‌گشت و همه شاگردان را استوار می‌نمود."},{"v":24,"t":"اما شخصی یهود اپلس نام از اهل اسکندریه که مردی فصیح و در کتاب توانا بود، به افسس رسید."},{"v":25,"t":"او درطریق خداوند تربیت یافته و در روح سرگرم بوده، درباره خداوند به دقت تکلم و تعلیم می‌نمود هر‌چند چز از تعمید یحیی اطلاعی نداشت."},{"v":26,"t":"همان شخص در کنیسه به دلیری سخن آغاز کرد اما چون پرسکله و اکیلا او راشنیدند، نزد خود آوردند و به دقت تمام طریق خدا را بدو آموختند."},{"v":27,"t":"پس چون اوعزیمت سفر اخائیه کرد، برادران او راترغیب نموده، به شاگردان سفارش نامه‌ای نوشتند که او را بپذیرند. و چون بدانجا رسیدآنانی را که به وسیله فیض ایمان آورده بودند، اعانت بسیار نمود،"},{"v":28,"t":"زیرا به قوت تمام بر یهوداقامه حجت می‌کرد و از کتب ثابت می‌نمود که عیسی، مسیح است."}],"en":[{"v":1,"t":"After these things Paul departed from Athens and came to Corinth."},{"v":2,"t":"He found a certain Jew named Aquila, a man of Pontus by race, who had recently come from Italy with his wife Priscilla, because Claudius had commanded all the Jews to depart from Rome. He came to them,"},{"v":3,"t":"and because he practiced the same trade, he lived with them and worked, for by trade they were tent makers."},{"v":4,"t":"He reasoned in the synagogue every Sabbath and persuaded Jews and Greeks."},{"v":5,"t":"When Silas and Timothy came down from Macedonia, Paul was compelled by the Spirit, testifying to the Jews that Jesus was the Christ."},{"v":6,"t":"When they opposed him and blasphemed, he shook out his clothing and said to them, “Your blood be on your own heads! I am clean. From now on, I will go to the Gentiles!”"},{"v":7,"t":"He departed there and went into the house of a certain man named Justus, one who worshiped God, whose house was next door to the synagogue."},{"v":8,"t":"Crispus, the ruler of the synagogue, believed in the Lord with all his house. Many of the Corinthians, when they heard, believed and were baptized."},{"v":9,"t":"The Lord said to Paul in the night by a vision, “Don’t be afraid, but speak and don’t be silent;"},{"v":10,"t":"for I am with you, and no one will attack you to harm you, for I have many people in this city.”"},{"v":11,"t":"He lived there a year and six months, teaching the word of God among them."},{"v":12,"t":"But when Gallio was proconsul of Achaia, the Jews with one accord rose up against Paul and brought him before the judgment seat,"},{"v":13,"t":"saying, “This man persuades men to worship God contrary to the law.”"},{"v":14,"t":"But when Paul was about to open his mouth, Gallio said to the Jews, “If indeed it were a matter of wrong or of wicked crime, you Jews, it would be reasonable that I should bear with you;"},{"v":15,"t":"but if they are questions about words and names and your own law, look to it yourselves. For I don’t want to be a judge of these matters.”"},{"v":16,"t":"So he drove them from the judgment seat."},{"v":17,"t":"Then all the Greeks seized Sosthenes, the ruler of the synagogue, and beat him before the judgment seat. Gallio didn’t care about any of these things."},{"v":18,"t":"Paul, having stayed after this many more days, took his leave of the brothers, and sailed from there for Syria, together with Priscilla and Aquila. He shaved his head in Cenchreae, for he had a vow."},{"v":19,"t":"He came to Ephesus, and he left them there; but he himself entered into the synagogue and reasoned with the Jews."},{"v":20,"t":"When they asked him to stay with them a longer time, he declined;"},{"v":21,"t":"but taking his leave of them, he said, “I must by all means keep this coming feast in Jerusalem, but I will return again to you if God wills.” Then he set sail from Ephesus."},{"v":22,"t":"When he had landed at Caesarea, he went up and greeted the assembly, and went down to Antioch."},{"v":23,"t":"Having spent some time there, he departed and went through the region of Galatia and Phrygia, in order, establishing all the disciples."},{"v":24,"t":"Now a certain Jew named Apollos, an Alexandrian by race, an eloquent man, came to Ephesus. He was mighty in the Scriptures."},{"v":25,"t":"This man had been instructed in the way of the Lord; and being fervent in spirit, he spoke and taught accurately the things concerning Jesus, although he knew only the baptism of John."},{"v":26,"t":"He began to speak boldly in the synagogue. But when Priscilla and Aquila heard him, they took him aside, and explained to him the way of God more accurately."},{"v":27,"t":"When he had determined to pass over into Achaia, the brothers encouraged him; and wrote to the disciples to receive him. When he had come, he greatly helped those who had believed through grace;"},{"v":28,"t":"for he powerfully refuted the Jews, publicly showing by the Scriptures that Jesus was the Christ."}],"hr":[{"v":1,"t":"Nakon toga napusti Pavao Atenu i ode u Korint."},{"v":2,"t":"Ondje nađe nekog Židova imenom Akvilu, rodom iz Ponta, koji netom bijaše došao iz Italije sa svojom ženom Priscilom jer je Klaudije naredio da svi Židovi napuste Rim. Pohodio ih je"},{"v":3,"t":"i, kako bijahu istog zanimanja, ostao kod njih i radio. Po zanimanju bijahu šatorari."},{"v":4,"t":"Svake je pak subote raspravljao u sinagogi i uvjeravao Židove i Grke."},{"v":5,"t":"Kad iz Makedonije pristigoše Sila i Timotej, Pavao se potpuno posveti Riječi svjedočeći Židovima da Isus jest Krist."},{"v":6,"t":"Kako se pak oni stadoše protiviti i huliti, otrese on haljine i reče im: “Krv vaša na glave vaše! Ja sam nedužan. Od sada idem k poganima.”"},{"v":7,"t":"I ode odande te prijeđe u kuću nekoga bogobojazna čovjeka, imenom Ticija Justa, čija kuća bijaše tik do sinagoge."},{"v":8,"t":"A nadstojnik sinagoge Krisp povjerova Gospodinu zajedno sa svim svojim domom. I mnogi od Korinćana koji su to slušali povjerovaše i pokrstiše se."},{"v":9,"t":"Jedne noći reče Gospodin Pavlu u viđenju: “Ne boj se, nego govori i ne daj se ušutkati!"},{"v":10,"t":"Ta ja sam s tobom i nitko se neće usuditi da ti naudi. Jer mnogo je naroda mojega u ovome gradu.”"},{"v":11,"t":"Tako se zadrža godinu i šest mjeseci naučavajući među njima riječ Božju."},{"v":12,"t":"Ali dok je Galion bio prokonzul Ahaje, navališe Židovi jednodušno na Pavla, dovukoše ga u sudnicu"},{"v":13,"t":"i rekoše: “Ovaj potiče ljude da protiv zakona štuju Boga.”"},{"v":14,"t":"Pavao samo što nije zaustio kadli Galion reče Židovima: “Da je posrijedi zločin kakav ili nedjelo opako, saslušao bih vas, Židovi, kako je pravo;"},{"v":15,"t":"je li pak raspra o riječi i imenima i o nekom vašem zakonu, proviđajte sami; u tome ja ne želim biti sudac.”"},{"v":16,"t":"I otpremi ih iz sudnice."},{"v":17,"t":"A oni svi pograbiše nadstojnika sinagoge Sostena i stadoše ga šibati pred sudnicom. Galion nije za to ništa mario."},{"v":18,"t":"Pavao osta još podosta vremena, a onda se oprosti s braćom pa pošto se u Kenhreji ošiša jer imaše zavjet, zaplovi prema Siriji, a s njime i Priscila i Akvila."},{"v":19,"t":"Stigoše u Efez. Tu ih ostavi, a on uđe u sinagogu i stade raspravljati sa Židovima."},{"v":20,"t":"Oni ga zamole da ostanu duže vremena, ali on ne pristade,"},{"v":21,"t":"nego se oprosti: “Još ću se, reče, vratiti k vama, bude li Božja volja.” I otplovi iz Efeza."},{"v":22,"t":"Kad stiže u Cezareju, uziđe pozdraviti Crkvu pa onda siđe u Antiohiju."},{"v":23,"t":"Neko se vrijeme zadrža pa onda ode i zareda galacijskim područjem i Frigijom utvrđujući sve učenike."},{"v":24,"t":"Uto neki Židov imenom Apolon, rodom Aleksandrijac, čovjek rječit i upućen u Pisma, stiže u Efez."},{"v":25,"t":"On bijaše upućen u Put Gospodnji pa je vatrene duše govorio i naučavao pomno o Isusu, premda je znao samo za Ivanovo krštenje."},{"v":26,"t":"Poče on tako smjelo govoriti u sinagogi. Čuše ga Priscila i Akvila, uzeše ga k sebi i pomnije mu izložiše Put Božji."},{"v":27,"t":"A kad je nakanio otići u Ahaju, ohrabriše ga braća i napisaše učenicima da ga prime. Kad je stigao onamo, uvelike je koristio vjernicima po milosti"},{"v":28,"t":"jer je snažno pobijao Židove javno pokazujući iz Pisama da Isus jest Krist."}]},"19":{"fa":[{"v":1,"t":"و چون اپلس در قرنتس بود، پولس درنواحی بالا گردش کرده، به افسس رسید. و در آنجا شاگرد چند یافته،"},{"v":2,"t":"بدیشان گفت: «آیا هنگامی که ایمان آوردید، روح‌القدس را یافتید؟» به وی گفتند: «بلکه نشنیدیم که روح‌القدس هست!»"},{"v":3,"t":"بدیشان گفت: «پس به چه چیز تعمید یافتید؟» گفتند: «به تعمید یحیی.»"},{"v":4,"t":"پولس گفت: «یحیی البته تعمید توبه می‌داد و به قوم می‌گفت به آن کسی‌که بعد از من می‌آید ایمان بیاورید یعنی به مسیح عیسی.»"},{"v":5,"t":"چون این راشنیدند به نام خداوند عیسی تعمید گرفتند،"},{"v":6,"t":"وچون پولس دست بر ایشان نهاد، روح‌القدس برایشان نازل شد و به زبانها متکلم گشته، نبوت کردند."},{"v":7,"t":"و جمله آن مردمان تخمین دوازده نفربودند."},{"v":8,"t":"پس به کنیسه درآمده، مدت سه ماه به دلیری سخن می‌راند و در امور ملکوت خدا مباحثه می‌نمود و برهان قاطع می‌آورد."},{"v":9,"t":"اما چون بعضی سخت دل گشته، ایمان نیاوردند و پیش روی خلق، طریقت را بد می‌گفتند، از ایشان کناره گزیده، شاگردان را جدا ساخت و هر روزه درمدرسه شخصی طیرانس نام مباحثه می‌نمود."},{"v":10,"t":"و بدینطور دو سال گذشت بقسمی که تمامی اهل آسیا چه یهود و چه یونانی کلام خداوندعیسی را شنیدند."},{"v":11,"t":"و خداوند از دست پولس معجزات غیرمعتاد به ظهور می‌رسانید،"},{"v":12,"t":"بطوری که از بدن او دستمالها و فوطه‌ها برده، بر مریضان می‌گذاردند و امراض از ایشان زایل می شد و ارواح پلید از ایشان اخراج می‌شدند."},{"v":13,"t":"لیکن تنی چند از یهودیان سیاح عزیمه خوان بر آنانی که ارواح پلید داشتند، نام خداوند عیسی را خواندن گرفتند و می‌گفتند: «شما را به آن عیسی که پولس به او موعظه می‌کندقسم می‌دهیم!»"},{"v":14,"t":"و هفت نفر پسران اسکیوارئیس کهنه یهود این کار می‌کردند."},{"v":15,"t":"اما روح خبیث در جواب ایشان گفت: «عیسی رامی شناسم و پولس را می‌دانم. لیکن شماکیستید؟»"},{"v":16,"t":"و آن مرد که روح پلید داشت برایشان جست و بر ایشان زورآور شده، غلبه یافت بحدی که از آن خانه عریان و مجروح فرار کردند."},{"v":17,"t":"چون این واقعه بر جمیع یهودیان و یونانیان ساکن افسس مشهور گردید، خوف بر همه ایشان طاری گشته، نام خداوند عیسی را مکرم می‌داشتند."},{"v":18,"t":"و بسیاری از آنانی که ایمان آورده بودند آمدند و به اعمال خود اعتراف کرده، آنها رافاش می‌نمودند."},{"v":19,"t":"و جمعی از شعبده بازان کتب خویش را آورده، در حضور خلق سوزانیدند وچون قیمت آنها را حساب کردند، پنجاه هزاردرهم بود"},{"v":20,"t":"بدینطور کلام خداوند ترقی کرده قوت می‌گرفت."},{"v":21,"t":"و بعد از تمام شدن این مقدمات، پولس درروح عزیمت کرد که از مکادونیه و اخائیه گذشته، به اورشلیم برود و گفت: «بعد از رفتنم به آنجا روم را نیز باید دید.»"},{"v":22,"t":"پس دو نفر از ملازمان خودیعنی تیموتاوس و ارسطوس را به مکادونیه روانه کرد و خود در آسیا چندی توقف نمود."},{"v":23,"t":"در آن زمان هنگامه‌ای عظیم درباره طریقت بر پا شد."},{"v":24,"t":"زیرا شخصی دیمیتریوس نام زرگر که تصاویربتکده ارطامیس از نقره می‌ساخت و بجهت صنعتگران نفع خطیر پیدا می‌نمود، ایشان را و دیگرانی که در چنین پیشه اشتغال می‌داشتند،"},{"v":25,"t":"فراهم آورده، گفت: «ای مردمان شما آگاه هستید که از این شغل، فراخی رزق ما است."},{"v":26,"t":"ودیده و شنیده‌اید که نه‌تنها در افسس، بلکه تقریب در تمام آسیا این پولس خلق بسیاری را اغوانموده، منحرف ساخته است و می‌گوید اینهایی که به‌دستها ساخته می‌شوند، خدایان نیستند."},{"v":27,"t":"پس خطر است که نه فقط کسب ما از میان رودبلکه این هیکل خدای عظیم ارطامیس نیز حقیرشمرده شود و عظمت وی که تمام آسیا و ربع مسکون او را می‌پرستند برطرف شود.»"},{"v":28,"t":"چون این را شنیدند، از خشم پر گشته، فریاد کرده، می‌گفتند که «بزرگ است ارطامیس افسسیان.»"},{"v":29,"t":"و تمامی شهر به شورش آمده، همه متفق به تماشاخانه تاختند و غایوس و ارسترخس را که از اهل مکادونیه و همراهان پولس بودند با خودمی کشیدند."},{"v":30,"t":"اما چون پولس اراده نمود که به میان مردم درآید، شاگردان او را نگذاشتند."},{"v":31,"t":"وبعضی از روسای آسیا که او را دوست می‌داشتند، نزد او فرستاده، خواهش نمودند که خود را به تماشاخانه نسپارد."},{"v":32,"t":"و هر یکی صدایی علیحده می‌کردند زیرا که جماعت آشفته بود و اکثرنمی دانستند که برای چه جمع شده‌اند."},{"v":33,"t":"پس اسکندر را از میان خلق کشیدند که یهودیان او راپیش انداختند و اسکندر به‌دست خود اشاره کرده، خواست برای خود پیش مردم حجت بیاورد."},{"v":34,"t":"لیکن چون دانستند که یهودی است همه به یک آواز قریب به دو ساعت ندا می‌کردندکه «بزرگ است ارطامیس افسسیان.»"},{"v":35,"t":"پس از آن مستوفی شهر خلق را ساکت گردانیده، گفت: «ای مردان افسسی، کیست که نمی داند که شهر افسسیان ارطامیس خدای عظیم و آن صنمی را که از مشتری نازل شد پرستش می‌کند؟"},{"v":36,"t":"پس چون این امور را نتوان انکار کرد، شما می‌باید آرام باشید و هیچ کاری به تعجیل نکنید."},{"v":37,"t":"زیرا که این اشخاص را آوردید که نه تاراج کنندگان هیکل‌اند و نه به خدای شما بدگفته‌اند."},{"v":38,"t":"پس هر گاه دیمیتریوس و همکاران وی ادعایی بر کسی دارند، ایام قضا مقرر است وداوران معین هستند. با همدیگر مرافعه باید کرد."},{"v":39,"t":"و اگر در امری دیگر طالب چیزی باشید، درمحکمه شرعی فیصل خواهد پذیرفت."},{"v":40,"t":"زیرادر خطریم که در خصوص فتنه امروز از مابازخواست شود چونکه هیچ علتی نیست که درباره آن عذری برای این ازدحام توانیم آورد.»"}],"en":[{"v":1,"t":"While Apollos was at Corinth, Paul, having passed through the upper country, came to Ephesus and found certain disciples."},{"v":2,"t":"He said to them, “Did you receive the Holy Spirit when you believed?” They said to him, “No, we haven’t even heard that there is a Holy Spirit.”"},{"v":3,"t":"He said, “Into what then were you baptized?” They said, “Into John’s baptism.”"},{"v":4,"t":"Paul said, “John indeed baptized with the baptism of repentance, saying to the people that they should believe in the one who would come after him, that is, in Christ Jesus.”"},{"v":5,"t":"When they heard this, they were baptized in the name of the Lord Jesus."},{"v":6,"t":"When Paul had laid his hands on them, the Holy Spirit came on them and they spoke with other languages and prophesied."},{"v":7,"t":"They were about twelve men in all."},{"v":8,"t":"He entered into the synagogue and spoke boldly for a period of three months, reasoning and persuading about the things concerning God’s Kingdom."},{"v":9,"t":"But when some were hardened and disobedient, speaking evil of the Way before the multitude, he departed from them and separated the disciples, reasoning daily in the school of Tyrannus."},{"v":10,"t":"This continued for two years, so that all those who lived in Asia heard the word of the Lord Jesus, both Jews and Greeks."},{"v":11,"t":"God worked special miracles by the hands of Paul,"},{"v":12,"t":"so that even handkerchiefs or aprons were carried away from his body to the sick, and the diseases departed from them, and the evil spirits went out."},{"v":13,"t":"But some of the itinerant Jews, exorcists, took on themselves to invoke over those who had the evil spirits the name of the Lord Jesus, saying, “We adjure you by Jesus whom Paul preaches.”"},{"v":14,"t":"There were seven sons of one Sceva, a Jewish chief priest, who did this."},{"v":15,"t":"The evil spirit answered, “Jesus I know, and Paul I know, but who are you?”"},{"v":16,"t":"The man in whom the evil spirit was leaped on them, overpowered them, and prevailed against them, so that they fled out of that house naked and wounded."},{"v":17,"t":"This became known to all, both Jews and Greeks, who lived at Ephesus. Fear fell on them all, and the name of the Lord Jesus was magnified."},{"v":18,"t":"Many also of those who had believed came, confessing and declaring their deeds."},{"v":19,"t":"Many of those who practiced magical arts brought their books together and burned them in the sight of all. They counted their price, and found it to be fifty thousand pieces of silver."},{"v":20,"t":"So the word of the Lord was growing and becoming mighty."},{"v":21,"t":"Now after these things had ended, Paul determined in the Spirit, when he had passed through Macedonia and Achaia, to go to Jerusalem, saying, “After I have been there, I must also see Rome.”"},{"v":22,"t":"Having sent into Macedonia two of those who served him, Timothy and Erastus, he himself stayed in Asia for a while."},{"v":23,"t":"About that time there arose no small disturbance concerning the Way."},{"v":24,"t":"For a certain man named Demetrius, a silversmith who made silver shrines of Artemis, brought no little business to the craftsmen,"},{"v":25,"t":"whom he gathered together with the workmen of like occupation, and said, “Sirs, you know that by this business we have our wealth."},{"v":26,"t":"You see and hear that not at Ephesus alone, but almost throughout all Asia, this Paul has persuaded and turned away many people, saying that they are no gods that are made with hands."},{"v":27,"t":"Not only is there danger that this our trade come into disrepute, but also that the temple of the great goddess Artemis will be counted as nothing and her majesty destroyed, whom all Asia and the world worships.”"},{"v":28,"t":"When they heard this they were filled with anger, and cried out, saying, “Great is Artemis of the Ephesians!”"},{"v":29,"t":"The whole city was filled with confusion, and they rushed with one accord into the theater, having seized Gaius and Aristarchus, men of Macedonia, Paul’s companions in travel."},{"v":30,"t":"When Paul wanted to enter in to the people, the disciples didn’t allow him."},{"v":31,"t":"Certain also of the Asiarchs, being his friends, sent to him and begged him not to venture into the theater."},{"v":32,"t":"Some therefore cried one thing, and some another, for the assembly was in confusion. Most of them didn’t know why they had come together."},{"v":33,"t":"They brought Alexander out of the multitude, the Jews putting him forward. Alexander beckoned with his hand, and would have made a defense to the people."},{"v":34,"t":"But when they perceived that he was a Jew, all with one voice for a time of about two hours cried out, “Great is Artemis of the Ephesians!”"},{"v":35,"t":"When the town clerk had quieted the multitude, he said, “You men of Ephesus, what man is there who doesn’t know that the city of the Ephesians is temple keeper of the great goddess Artemis, and of the image which fell down from Zeus?"},{"v":36,"t":"Seeing then that these things can’t be denied, you ought to be quiet and to do nothing rash."},{"v":37,"t":"For you have brought these men here, who are neither robbers of temples nor blasphemers of your goddess."},{"v":38,"t":"If therefore Demetrius and the craftsmen who are with him have a matter against anyone, the courts are open and there are proconsuls. Let them press charges against one another."},{"v":39,"t":"But if you seek anything about other matters, it will be settled in the regular assembly."},{"v":40,"t":"For indeed we are in danger of being accused concerning today’s riot, there being no cause. Concerning it, we wouldn’t be able to give an account of this commotion.”"}],"hr":[{"v":1,"t":"Dok je Apolon bio u Korintu, Pavao, pošto prođe gornje krajeve, dođe u Efez, nađe neke učenike"},{"v":2,"t":"pa ih upita: “Jeste li primili Duha Svetoga kad ste povjerovali?” Oni će mu: “Ta ni čuli nismo da ima Duh Sveti.”"},{"v":3,"t":"Nato će on: “Kako ste onda kršteni?” “Krštenjem Ivanovim”, odvrate oni."},{"v":4,"t":"Nato će Pavao: “Ivan je krstio krštenjem obraćenja govoreći narodu da vjeruje u Onoga koji za njim dolazi, to jest u Isusa.”"},{"v":5,"t":"Čuvši to, krste se u ime Gospodina Isusa,"},{"v":6,"t":"pa kad Pavao položi na njih ruke, dođe Duh Sveti na njih te stanu govoriti drugim jezicima i prorokovati."},{"v":7,"t":"Bijaše u svemu dvanaestak muževa."},{"v":8,"t":"Onda Pavao uđe u sinagogu te je tri mjeseca hrabro raspravljao i uvjeravao o kraljevstvu Božjem."},{"v":9,"t":"Ali kako neki, okorjeli i nepokorni, ocrnjivahu ovaj Put pred mnoštvom, odstupi od njih, odvoji učenike i danomice raspravljaše u školi nekog Tirana."},{"v":10,"t":"Trajalo je to dvije godine, tako da su svi azijski žitelji, Židovi i Grci, čuli riječ Božju."},{"v":11,"t":"Bog je pak činio čudesa nesvakidašnja po rukama Pavlovima"},{"v":12,"t":"tako da bi na bolesnike stavljali rupce ili rublje s Pavlova tijela pa bi s njih nestajalo bolesti i zli duhovi iz njih izlazili."},{"v":13,"t":"Zato i neki Židovi zaklinjaoci-potukači pokušaše zazvati ime Gospodina Isusa nad one koji imahu zle duhove. Govorili su: “Zaklinjem vas Isusom koga Pavao propovijeda.”"},{"v":14,"t":"To činjaše sedam sinova nekog Skeve, židovskoga velikog svećenika."},{"v":15,"t":"Zli im duh odvrati: “Isusa poznajem i Pavla znam, ali tko ste vi?”"},{"v":16,"t":"I čovjek u kome bijaše zli duh, nasrnu na njih i nadjača ih te oni goli i izranjeni pobjegoše iz one kuće."},{"v":17,"t":"Doznaše to svi žitelji efeški, Židovi i Grci, pa ih sve obuze strah te se stade veličati ime Gospodina Isusa."},{"v":18,"t":"Mnogi pak od onih koji su povjerovali dolazili su ispovijedati i očitovati svoja djela."},{"v":19,"t":"I podosta onih koji su se bavili praznovjerjem donosili su knjige i spaljivali ih pred svima. Procijeniše ih te nađoše da vrijede pedeset tisuća srebrnjaka."},{"v":20,"t":"TAko se snagom Gospodnjom Riječ širila i jačala."},{"v":21,"t":"Pošto se to ispuni, naumi Pavao preko Makedonije i Ahaje otići u Jeruzalem te reče: “Pošto budem ondje, trebat će da i Rim vidim.”"},{"v":22,"t":"Onda posla u Makedoniju dvojicu svojih poslužitelja, Timoteja i Erasta, a on provede još neko vrijeme u Aziji."},{"v":23,"t":"Nekako u ono doba nasta nemalena pobuna protiv ovog Puta."},{"v":24,"t":"Neki srebrar, imenom Demetrije, izrađivao je srebrne hramiće Artemidine i namicao obrtnicima nemalu dobit."},{"v":25,"t":"Skupi on njih i sve koji su se bavili takvim poslom te im reče: “Ljudi, vi znate, u ovom je umijeću naše blagostanje."},{"v":26,"t":"A vidite i čujete da je taj Pavao ne samo u Efezu nego gotovo i u svoj Aziji uvjerio i preokrenuo poveliko mnoštvo govoreći da nema bogova rukama izdjeljanih."},{"v":27,"t":"Tako prijeti opasnost ne samo da na zao glas dođe naše zanimanje, nego i to da se ništa neće držati do hrama velike božice Artemide te će nestati veličanstva one koju štuje sva Azija i sav svijet.”"},{"v":28,"t":"Čuvši to, razgnjeve se pa poviču: “Velika je Artemida efeška!”"},{"v":29,"t":"Sav se grad uskomeša; jednodušno nahrupe u kazalište vukući sa sobom Makedonce Gaja i Aristarha, suputnike Pavlove."},{"v":30,"t":"Kad je Pavao htio među narod, ne dopustiše mu učenici."},{"v":31,"t":"Čak i neki azijarsi, njegovi prijatelji, poslaše k njemu i zamoliše da ne dolazi u kazalište."},{"v":32,"t":"Jedni su izvikivali jedno, drugi drugo jer je skup bio uskomešan te mnogi nisu ni znali zašto su se strčali."},{"v":33,"t":"Neki iz svjetine uputiše nekog Aleksandra jer su ga Židovi gurali naprijed. Aleksandar pak mahnu rukom i htjede se obraniti pred narodom."},{"v":34,"t":"Ali kada doznaše da je Židov, udarahu gotovo dva sata svi u jedan glas: “Velika je Artemida efeška!”"},{"v":35,"t":"Onda tajnik umiri svjetinu pa reče: “Efežani! Tko to od ljudi ne zna da je grad Efez čuvar hrama velike Artemide i kipa s neba palog?"},{"v":36,"t":"Budući dakle da je to neporecivo, valja da budete mirni te ništa brzopleto ne činite."},{"v":37,"t":"Doveli ste ove ljude, a nisu ni svetokradice ni hulitelji naše božice."},{"v":38,"t":"Ako pak Demetrije i njegovi obrtnici imaju protiv koga kakvu tužbu, sudovi se sastaju, a tu su i prokonzuli. Neka se tuže!"},{"v":39,"t":"Ištete li pak što drugo, u zakonitu će se skupu riješiti."},{"v":40,"t":"Ta izlažemo se opasnosti da za ovo današnje budemo optuženi s pobune jer nema nikakva razloga kojim bismo mogli opravdati ovu strku.” To rekavši, raspusti skup."}]},"20":{"fa":[{"v":1,"t":"و بعد از تمام شدن این هنگامه، پولس شاگردان را طلبیده، ایشان را وداع نمودو به سمت مکادونیه روانه شد."},{"v":2,"t":"و در آن نواحی سیر کرده، اهل آنجا را نصیحت بسیار نمود و به یونانستان آمد."},{"v":3,"t":"و سه ماه توقف نمود و چون عزم سفر سوریه کرد و یهودیان در کمین وی بودند، اراده نمود که از راه مکادونیه مراجعت کند."},{"v":4,"t":"و سوپاترس از اهل بیریه و ارسترخس وسکندس از اهل تسالونیکی و غایوس از دربه وتیموتاوس و از مردم آسیا تیخیکس و تروفیمس تا به آسیا همراه او رفتند."},{"v":5,"t":"و ایشان پیش رفته، درترواس منتظر ما شدند."},{"v":6,"t":"و اما ما بعد از ایام فطیراز فیلپی به کشتی سوار شدیم و بعد از پنج روز به ترواس نزد ایشان رسیده، در آنجا هفت روزماندیم."},{"v":7,"t":"و در اول هفته چون شاگردان بجهت شکستن نان جمع شدند و پولس در فردای آن روز عازم سفر بود، برای ایشان موعظه می‌کرد و سخن او تانصف شب طول کشید."},{"v":8,"t":"و در بالاخانه‌ای که جمع بودیم چراغ بسیار بود."},{"v":9,"t":"ناگاه جوانی که افتیخس نام داشت، نزد دریچه نشسته بود که خواب سنگین او را درربود و چون پولس کلام راطول می‌داد، خواب بر او مستولی گشته، از طبقه سوم به زیر افتاد و او را مرده برداشتند."},{"v":10,"t":"آنگاه پولس به زیر آمده، بر او افتاد و وی را در آغوش کشیده، گفت: «مضطرب مباشید زیرا که جان اودر اوست.»"},{"v":11,"t":"پس بالا رفته و نان را شکسته، خورد و تا طلوع فجر گفتگوی بسیار کرده، همچنین روانه شد."},{"v":12,"t":"و آن جوان را زنده بردند وتسلی عظیم پذیرفتند."},{"v":13,"t":"اما ما به کشتی سوار شده، به اسوس پیش رفتیم که از آنجا می‌بایست پولس را برداریم که بدینطور قرار داد زیرا خواست تا آنجا پیاده رود."},{"v":14,"t":"پس چون در اسوس او را ملاقات کردیم، او رابرداشته، به متیلینی آمدیم."},{"v":15,"t":"و از آنجا به دریاکوچ کرده، روز دیگر به مقابل خیوس رسیدیم وروز سوم به ساموس وارد شدیم و در تروجیلیون توقف نموده، روز دیگر وارد میلیتس شدیم."},{"v":16,"t":"زیرا که پولس عزیمت داشت که از محاذی افسس بگذرد، مبادا او را در آسیا درنگی پیداشود، چونکه تعجیل می‌کرد که اگر ممکن شود تاروز پنطیکاست به اورشلیم برسد."},{"v":17,"t":"پس از میلیتس به افسس فرستاده، کشیشان کلیسا را طلبید."},{"v":18,"t":"و چون به نزدش حاضر شدند، ایشان را گفت: «بر شما معلوم است که از روز اول که وارد آسیا شدم، چطور هر وقت با شما بسرمی بردم؛"},{"v":19,"t":"که با کمال فروتنی و اشکهای بسیار وامتحانهایی که از مکاید یهود بر من عارض می‌شد، به خدمت خداوند مشغول می‌بودم."},{"v":20,"t":"وچگونه چیزی را از آنچه برای شما مفید باشد، دریغ نداشتم بلکه آشکارا و خانه به خانه شما رااخبار و تعلیم می‌نمودم."},{"v":21,"t":"و به یهودیان ویونانیان نیز از توبه به سوی خدا و ایمان به خداوند ما عیسی مسیح شهادت می‌دادم."},{"v":22,"t":"واینک الان در روح بسته شده، به اورشلیم می‌روم و از آنچه در آنجا بر من واقع خواهد شد، اطلاعی ندارم."},{"v":23,"t":"جز اینکه روح‌القدس در هر شهرشهادت داده، می‌گوید که بندها و زحمات برایم مهیا است."},{"v":24,"t":"لیکن این چیزها را به هیچ می‌شمارم، بلکه جان خود را عزیز نمی دارم تادور خود را به خوشی به انجام رسانم و آن خدمتی را که از خداوند عیسی یافته‌ام که به بشارت فیض خدا شهادت دهم."},{"v":25,"t":"و الحال این رامی دانم که جمیع شما که در میان شما گشته و به ملکوت خدا موعظه کرده‌ام، دیگر روی مرانخواهید دید."},{"v":26,"t":"پس امروز از شما گواهی می‌طلبم که من از خون همه بری هستم،"},{"v":27,"t":"زیراکه از اعلام نمودن شما به تمامی اراده خداکوتاهی نکردم."},{"v":28,"t":"پس نگاه دارید خویشتن وتمامی آن گله را که روح‌القدس شما را بر آن اسقف مقرر فرمود تا کلیسای خدا را رعایت کنیدکه آن را به خون خود خریده است."},{"v":29,"t":"زیرا من می‌دانم که بعد از رحلت من، گرگان درنده به میان شما درخواهند آمد که بر گله ترحم نخواهند نمود،"},{"v":30,"t":"و از میان خود شما مردمانی خواهندبرخاست که سخنان کج خواهند گفت تا شاگردان را در عقب خود بکشند."},{"v":31,"t":"لهذا بیدار باشید و به یاد آورید که مدت سه سال شبانه‌روز از تنبیه نمودن هر یکی از شما با اشکها باز نایستادم."},{"v":32,"t":"والحال‌ای برادران شما را به خدا و به کلام فیض اومی سپارم که قادر است شما را بنا کند و در میان جمیع مقدسین شما را میراث بخشد."},{"v":33,"t":"نقره یاطلا یا لباس کسی را طمع نورزیدم،"},{"v":34,"t":"بلکه خودمی دانید که همین دستها در رفع احتیاج خود ورفقایم خدمت می‌کرد."},{"v":35,"t":"این همه را به شمانمودم که می‌باید چنین مشقت کشیده، ضعفا رادستگیری نمایید و کلام خداوند عیسی را به‌خاطر دارید که او گفت دادن از گرفتن فرخنده‌تراست.»"},{"v":36,"t":"این بگفت و زانو زده، با همگی ایشان دعاکرد."},{"v":37,"t":"و همه گریه بسیار کردند و بر گردن پولس آویخته، او را می‌بوسیدند."},{"v":38,"t":"و بسیار متالم شدندخصوص بجهت آن سخنی که گفت: «بعد از این‌روی مرا نخواهید دید.» پس او را تا به کشتی مشایعت نمودند."}],"en":[{"v":1,"t":"After the uproar had ceased, Paul sent for the disciples, took leave of them, and departed to go into Macedonia."},{"v":2,"t":"When he had gone through those parts and had encouraged them with many words, he came into Greece."},{"v":3,"t":"When he had spent three months there, and a plot was made against him by Jews as he was about to set sail for Syria, he determined to return through Macedonia."},{"v":4,"t":"These accompanied him as far as Asia: Sopater of Beroea, Aristarchus and Secundus of the Thessalonians, Gaius of Derbe, Timothy, and Tychicus and Trophimus of Asia."},{"v":5,"t":"But these had gone ahead, and were waiting for us at Troas."},{"v":6,"t":"We sailed away from Philippi after the days of Unleavened Bread, and came to them at Troas in five days, where we stayed seven days."},{"v":7,"t":"On the first day of the week, when the disciples were gathered together to break bread, Paul talked with them, intending to depart on the next day; and continued his speech until midnight."},{"v":8,"t":"There were many lights in the upper room where we were gathered together."},{"v":9,"t":"A certain young man named Eutychus sat in the window, weighed down with deep sleep. As Paul spoke still longer, being weighed down by his sleep, he fell down from the third floor and was taken up dead."},{"v":10,"t":"Paul went down and fell upon him, and embracing him said, “Don’t be troubled, for his life is in him.”"},{"v":11,"t":"When he had gone up, had broken bread and eaten, and had talked with them a long while, even until break of day, he departed."},{"v":12,"t":"They brought the boy in alive, and were greatly comforted."},{"v":13,"t":"But we, going ahead to the ship, set sail for Assos, intending to take Paul aboard there; for he had so arranged, intending himself to go by land."},{"v":14,"t":"When he met us at Assos, we took him aboard and came to Mitylene."},{"v":15,"t":"Sailing from there, we came the following day opposite Chios. The next day we touched at Samos and stayed at Trogyllium, and the day after we came to Miletus."},{"v":16,"t":"For Paul had determined to sail past Ephesus, that he might not have to spend time in Asia; for he was hastening, if it were possible for him, to be in Jerusalem on the day of Pentecost."},{"v":17,"t":"From Miletus he sent to Ephesus and called to himself the elders of the assembly."},{"v":18,"t":"When they had come to him, he said to them, “You yourselves know, from the first day that I set foot in Asia, how I was with you all the time,"},{"v":19,"t":"serving the Lord with all humility, with many tears, and with trials which happened to me by the plots of the Jews;"},{"v":20,"t":"how I didn’t shrink from declaring to you anything that was profitable, teaching you publicly and from house to house,"},{"v":21,"t":"testifying both to Jews and to Greeks repentance toward God and faith toward our Lord Jesus."},{"v":22,"t":"Now, behold, I go bound by the Spirit to Jerusalem, not knowing what will happen to me there;"},{"v":23,"t":"except that the Holy Spirit testifies in every city, saying that bonds and afflictions wait for me."},{"v":24,"t":"But these things don’t count; nor do I hold my life dear to myself, so that I may finish my race with joy, and the ministry which I received from the Lord Jesus, to fully testify to the Good News of the grace of God."},{"v":25,"t":"“Now, behold, I know that you all, among whom I went about preaching God’s Kingdom, will see my face no more."},{"v":26,"t":"Therefore I testify to you today that I am clean from the blood of all men,"},{"v":27,"t":"for I didn’t shrink from declaring to you the whole counsel of God."},{"v":28,"t":"Take heed, therefore, to yourselves and to all the flock, in which the Holy Spirit has made you overseers, to shepherd the assembly of the Lord and God which he purchased with his own blood."},{"v":29,"t":"For I know that after my departure, vicious wolves will enter in among you, not sparing the flock."},{"v":30,"t":"Men will arise from among your own selves, speaking perverse things, to draw away the disciples after them."},{"v":31,"t":"Therefore watch, remembering that for a period of three years I didn’t cease to admonish everyone night and day with tears."},{"v":32,"t":"Now, brothers, I entrust you to God and to the word of his grace, which is able to build up and to give you the inheritance among all those who are sanctified."},{"v":33,"t":"I coveted no one’s silver, gold, or clothing."},{"v":34,"t":"You yourselves know that these hands served my necessities, and those who were with me."},{"v":35,"t":"In all things I gave you an example, that so laboring you ought to help the weak, and to remember the words of the Lord Jesus, that he himself said, ‘It is more blessed to give than to receive.’ ”"},{"v":36,"t":"When he had spoken these things, he knelt down and prayed with them all."},{"v":37,"t":"They all wept freely, and fell on Paul’s neck and kissed him,"},{"v":38,"t":"sorrowing most of all because of the word which he had spoken, that they should see his face no more. Then they accompanied him to the ship."}],"hr":[{"v":1,"t":"Kad se sleže metež, posla Pavao po učenike, ohrabri ih, pozdravi i otputova u Makedoniju."},{"v":2,"t":"Prešavši one krajeve, hrabreći braću besjedom mnogom, dođe u Grčku"},{"v":3,"t":"i provede ondje tri mjeseca. Upravo kad je htio otploviti u Siriju, postaviše mu Židovi zasjedu pa odluči vratiti se preko Makedonije."},{"v":4,"t":"Pratili su ga: Sopater Pirov, Berejac, Solunjani Aristarh i Sekund, Gaj Derbanin, Timotej i Azijci Tihik i Trofim."},{"v":5,"t":"Oni odoše prije te nas dočekaše u Troadi."},{"v":6,"t":"Mi pak nakon dana Beskvasnih kruhova otplovismo iz Filipa i nakon pet dana dođosmo k njima u Troadu gdje proboravismo sedam dana."},{"v":7,"t":"U prvi dan tjedna, kad se sabrasmo lomiti kruh, Pavao im govoraše i kako je sutradan kanio otputovati, probesjedi sve do ponoći."},{"v":8,"t":"U gornjoj sobi gdje smo se sabrali bijaše dosta svjetiljaka."},{"v":9,"t":"Na prozoru je sjedio neki mladić imenom Eutih. Kako je Pavao dulje govorio, utone on u dubok san. Svladan snom, pade s trećeg kata dolje. Digoše ga mrtva."},{"v":10,"t":"Pavao siđe, nadnese se nad dječaka, obujmi ga i reče: “Ne uznemirujte se! Duša je još u njemu!”"},{"v":11,"t":"Zatim se pope pa pošto razlomi kruh i blagova, dugo je još zborio, sve do zore. Tad otputova."},{"v":12,"t":"Mladića odvedoše živa, neizmjerno utješeni."},{"v":13,"t":"Mi pak pođosmo naprijed lađom: otplovismo u As. Odande smo imali povesti Pavla - tako je odredio kad se spremao poći pješice."},{"v":14,"t":"Kad nam se u Asu pridruži, uzesmo ga i stigosmo u Mitilenu."},{"v":15,"t":"Odande odjedrismo sutradan i stigosmo nadomak Hija, prekosutra krenusmo u Sam, a idućeg dana stigosmo u Milet."},{"v":16,"t":"Jer Pavao je odlučio mimoići Efez da se ne bi zadržao u Aziji: žurio se da, uzmogne li, na dan Pedesetnice bude u Jeruzalemu."},{"v":17,"t":"Ipak iz Mileta posla u Efez po starješine Crkve."},{"v":18,"t":"Kad stigoše, reče im: “Vi znate kako sam se sve vrijeme, od prvog dana kada stupih u Aziju, ponašao među vama:"},{"v":19,"t":"služio sam Gospodinu sa svom poniznošću u suzama i kušnjama koje me zadesiše zbog zasjeda židovskih;"},{"v":20,"t":"ništa korisno nisam propustio navijestiti vam i naučiti vas - javno i po kućama;"},{"v":21,"t":"upozoravao sam Židove i Grke da se obrate k Bogu i da vjeruju u Gospodina našega Isusa.”"},{"v":22,"t":"“A sad, evo, okovan Duhom idem u Jeruzalem. Što će me u njemu zadesiti, ne znam,"},{"v":23,"t":"osim što mi Duh Sveti u svakom gradu jamči da me čekaju okovi i nevolje."},{"v":24,"t":"Ali ni najmanje mi nije do života, samo da dovršim trku svoju i službu koju primih od Gospodina Isusa: svjedočiti za evanđelje milosti Božje.”"},{"v":25,"t":"“I sad, evo, znam: nećete više vidjeti lica moga, svi vi posred kojih prođoh propovijedajući Kraljevstvo."},{"v":26,"t":"Zato vam u ovaj dan današnji jamčim: čist sam od krvi sviju"},{"v":27,"t":"jer nisam propustio navijestiti vam ništa od svega nauma Božjega.”"},{"v":28,"t":"“Pazite na sebe i na sve stado u kojem vas Duh Sveti postavi nadglednicima, da pasete Crkvu Božju koju steče krvlju svojom.”"},{"v":29,"t":"“Ja znam da će nakon mog odlaska među vas uljesti vuci okrutni koji ne štede stada,"},{"v":30,"t":"a između vas će samih ustati ljudi koji će iskrivljavati nauk da bi odvukli učenike za sobom."},{"v":31,"t":"Zato bdijte imajući na pameti da sam tri godine bez prestanka noću i danju suze lijevajući urazumljivao svakoga od vas.”"},{"v":32,"t":"“I sada vas povjeravam Bogu i Riječi milosti njegove koja je kadra izgraditi vas i dati vam baštinu među svima posvećenima.”"},{"v":33,"t":"“Ni za čijim srebrom, zlatom ili ruhom nisam hlepio."},{"v":34,"t":"Sami znate: za potrebe moje i onih koji su sa mnom zasluživale su ove ruke."},{"v":35,"t":"U svemu vam pokazah: tako se trudeći treba se zauzimati za nemoćne i na pameti imati riječi Gospodina Isusa jer on reče: 'Blaženije je davati nego primati.'”"},{"v":36,"t":"Kada to doreče, klekne te se zajedno sa svima njima pomoli."},{"v":37,"t":"Tad svi briznuše u velik plač, obisnuše Pavlu oko vrata i stadoše ga cjelivati,"},{"v":38,"t":"ražalošćeni nadasve riječju koju im reče: da više neće vidjeti lica njegova. Zatim ga ispratiše na lađu."}]},"21":{"fa":[{"v":1,"t":"و چون از ایشان هجرت نمودیم، سفردریا کردیم و به راه راست به کوس آمدیم و روز دیگر به رودس و از آنجا به پاترا."},{"v":2,"t":"وچون کشتی‌ای یافتیم که عازم فینیقیه بود، بر آن سوار شده، کوچ کردیم."},{"v":3,"t":"و قپرس را به نظرآورده، آن را به طرف چپ رها کرده، به سوی سوریه رفتیم و در صور فرود آمدیم زیرا که در آنجا می‌بایست بار کشتی را فرود آورند."},{"v":4,"t":"پس شاگردی چند پیدا کرده، هفت روز در آنجاماندیم و ایشان به الهام روح به پولس گفتند که به اورشلیم نرود."},{"v":5,"t":"و چون آن روزها را بسر بردیم، روانه گشتیم و همه با زنان و اطفال تا بیرون شهر مارا مشایعت نمودند و به کناره دریا زانو زده، دعاکردیم."},{"v":6,"t":"پس یکدیگر را وداع کرده، به کشتی سوار شدیم و ایشان به خانه های خود برگشتند."},{"v":7,"t":"و ما سفر دریا را به انجام رسانیده، از صور به پتولامیس رسیدیم و برادران را سلام کرده، باایشان یک روز ماندیم."},{"v":8,"t":"در فردای آن روز، ازآنجا روانه شده، به قیصریه آمدیم و به خانه فیلپس مبشر که یکی از آن هفت بود درآمده، نزداو ماندیم."},{"v":9,"t":"و او را چهار دختر باکره بود که نبوت می‌کردند."},{"v":10,"t":"و چون روز چند در آنجا ماندیم، نبی‌ای آغابوس نام از یهودیه رسید،"},{"v":11,"t":"و نزد ما آمده، کمربند پولس را گرفته و دستها و پایهای خود رابسته، گفت: «روح‌القدس می‌گوید که یهودیان دراورشلیم صاحب این کمربند را به همینطور بسته، او را به‌دستهای امت‌ها خواهند سپرد.»"},{"v":12,"t":"پس چون این را شنیدیم، ما و اهل آنجا التماس نمودیم که به اورشلیم نرود."},{"v":13,"t":"پولس جواب داد: «چه می‌کنید که گریان شده، دل مرا می‌شکنیدزیرا من مستعدم که نه فقط قید شوم بلکه تا دراورشلیم بمیرم به‌خاطر نام خداوند عیسی.»"},{"v":14,"t":"چون او نشنید خاموش شده، گفتیم: «آنچه اراده خداوند است بشود.»"},{"v":15,"t":"و بعد از آن ایام تدارک سفر دیده، متوجه اورشلیم شدیم."},{"v":16,"t":"و تنی چند از شاگردان قیصریه همراه آمده، ما را نزد شخصی مناسون نام که از اهل قپرس و شاگرد قدیمی بود، آوردند تانزد او منزل نماییم."},{"v":17,"t":"و چون وارد اورشلیم گشتیم، برادران ما رابه خشنودی پذیرفتند."},{"v":18,"t":"و در روز دیگر، پولس ما را برداشته، نزد یعقوب رفت و همه کشیشان حاضر شدند."},{"v":19,"t":"پس ایشان را سلام کرده، آنچه خدا بوسیله خدمت او در میان امت‌ها به عمل آورده بود، مفصلا گفت."},{"v":20,"t":"ایشان چون این راشنیدند، خدا را تمجید نموده، به وی گفتند: «ای برادر، آگاه هستی که چند هزارها از یهودیان ایمان آورده‌اند و جمیع در شریعت غیورند:"},{"v":21,"t":"ودرباره تو شنیده‌اند که همه یهودیان را که در میان امت‌ها می‌باشند، تعلیم می‌دهی که از موسی انحراف نمایند و می‌گویی نباید اولاد خود رامختون ساخت و به سنن رفتار نمود."},{"v":22,"t":"پس چه باید کرد؟ البته جماعت جمع خواهند شد زیراخواهند شنید که تو آمده‌ای."},{"v":23,"t":"پس آنچه به توگوییم به عمل آور: چهار مرد نزد ما هستند که برایشان نذری هست."},{"v":24,"t":"پس ایشان را برداشته، خود را با ایشان تطهیر نما و خرج ایشان را بده که سر خود را بتراشند تا همه بدانند که آنچه درباره تو شنیده‌اند اصلی ندارد بلکه خود نیز درمحافظت شریعت سلوک می‌نمایی."},{"v":25,"t":"لیکن درباره آنانی که از امت‌ها ایمان آورده‌اند، مافرستادیم و حکم کردیم که از قربانی های بت وخون و حیوانات خفه شده و زنا پرهیز نمایند."},{"v":26,"t":"پس پولس آن اشخاص را برداشته، روز دیگر با ایشان طهارت کرده، به هیکل درآمد و از تکمیل ایام طهارت اطلاع داد تا هدیه‌ای برای هر یک ازایشان بگذرانند."},{"v":27,"t":"و چون هفت روز نزدیک به انجام رسید، یهودی‌ای چند از آسیا او را در هیکل دیده، تمامی قوم را به شورش آوردند و دست بر اوانداخته،"},{"v":28,"t":"فریاد برآوردند که «ای مردان اسرائیلی، امداد کنید! این است آن کس که برخلاف امت و شریعت و این مکان در هر جاهمه را تعلیم می‌دهد. بلکه یونانی‌ای چند را نیز به هیکل درآورده، این مکان مقدس را ملوث نموده است.»"},{"v":29,"t":"زیرا قبل از آن تروفیمس افسسی را باوی در شهر دیده بودند و مظنه داشتند که پولس او را به هیکل آورده بود."},{"v":30,"t":"پس تمامی شهر به حرکت آمد و خلق ازدحام کرده، پولس را گرفتند و از هیکل بیرون کشیدند و فی الفور درها را بستند."},{"v":31,"t":"و چون قصدقتل او می‌کردند، خبر به مین باشی سپاه رسید که «تمامی اورشلیم به شورش آمده است.»"},{"v":32,"t":"اوبی درنگ سپاه و یوزباشی‌ها را برداشته، بر سرایشان تاخت. پس ایشان به مجرد دیدن مین باشی و سپاهیان، از زدن پولس دست برداشتند."},{"v":33,"t":"چون مین باشی رسید، او را گرفته، فرمان داد تا او را بدو زنجیر ببندند و پرسید که «این کیست و چه کرده است؟»"},{"v":34,"t":"اما بعضی از آن گروه به سخنی و بعضی به سخنی دیگر صدا می‌کردند. و چون او به‌سبب شورش، حقیقت امر رانتوانست فهمید، فرمود تا او را به قلعه بیاورند."},{"v":35,"t":"و چون به زینه رسید، اتفاق افتاد که لشکریان به‌سبب ازدحام مردم او را برگرفتند،"},{"v":36,"t":"زیرا گروهی کثیر از خلق از عقب او افتاده، صدا می‌زدند که «اورا هلاک کن!»"},{"v":37,"t":"چون نزدیک شد که پولس را به قلعه درآورند، او به مین باشی گفت: آیا اجازت است که به تو چیزی گویم؟ گفت: «آیا زبان یونانی رامی دانی؟"},{"v":38,"t":"مگر تو آن مصری نیستی که چندی پیش از این فتنه برانگیخته، چهار هزار مرد قتال رابه بیابان برد؟»"},{"v":39,"t":"پولس گفت: «من مرد یهودی هستم از طرسوس قیلیقیه، شهری که بی‌نام ونشان نیست و خواهش آن دارم که مرا اذن فرمایی تا به مردم سخن گویم.»"},{"v":40,"t":"چون اذن یافت، بر زینه ایستاده، به‌دست خود به مردم اشاره کرد؛ و چون آرامی کامل پیدا شد، ایشان را به زبان عبرانی مخاطب ساخته، گفت."}],"en":[{"v":1,"t":"When we had departed from them and had set sail, we came with a straight course to Cos, and the next day to Rhodes, and from there to Patara."},{"v":2,"t":"Having found a ship crossing over to Phoenicia, we went aboard and set sail."},{"v":3,"t":"When we had come in sight of Cyprus, leaving it on the left hand, we sailed to Syria and landed at Tyre, for the ship was there to unload her cargo."},{"v":4,"t":"Having found disciples, we stayed there seven days. These said to Paul through the Spirit that he should not go up to Jerusalem."},{"v":5,"t":"When those days were over, we departed and went on our journey. They all, with wives and children, brought us on our way until we were out of the city. Kneeling down on the beach, we prayed."},{"v":6,"t":"After saying goodbye to each other, we went on board the ship, and they returned home again."},{"v":7,"t":"When we had finished the voyage from Tyre, we arrived at Ptolemais. We greeted the brothers and stayed with them one day."},{"v":8,"t":"On the next day, we who were Paul’s companions departed and came to Caesarea. We entered into the house of Philip the evangelist, who was one of the seven, and stayed with him."},{"v":9,"t":"Now this man had four virgin daughters who prophesied."},{"v":10,"t":"As we stayed there some days, a certain prophet named Agabus came down from Judea."},{"v":11,"t":"Coming to us and taking Paul’s belt, he bound his own feet and hands, and said, “The Holy Spirit says: ‘So the Jews at Jerusalem will bind the man who owns this belt, and will deliver him into the hands of the Gentiles.’”"},{"v":12,"t":"When we heard these things, both we and the people of that place begged him not to go up to Jerusalem."},{"v":13,"t":"Then Paul answered, “What are you doing, weeping and breaking my heart? For I am ready not only to be bound, but also to die at Jerusalem for the name of the Lord Jesus.”"},{"v":14,"t":"When he would not be persuaded, we ceased, saying, “The Lord’s will be done.”"},{"v":15,"t":"After these days we took up our baggage and went up to Jerusalem."},{"v":16,"t":"Some of the disciples from Caesarea also went with us, bringing one Mnason of Cyprus, an early disciple, with whom we would stay."},{"v":17,"t":"When we had come to Jerusalem, the brothers received us gladly."},{"v":18,"t":"The day following, Paul went in with us to James; and all the elders were present."},{"v":19,"t":"When he had greeted them, he reported one by one the things which God had worked among the Gentiles through his ministry."},{"v":20,"t":"They, when they heard it, glorified God. They said to him, “You see, brother, how many thousands there are among the Jews of those who have believed, and they are all zealous for the law."},{"v":21,"t":"They have been informed about you, that you teach all the Jews who are among the Gentiles to forsake Moses, telling them not to circumcise their children and not to walk after the customs."},{"v":22,"t":"What then? The assembly must certainly meet, for they will hear that you have come."},{"v":23,"t":"Therefore do what we tell you. We have four men who have taken a vow."},{"v":24,"t":"Take them and purify yourself with them, and pay their expenses for them, that they may shave their heads. Then all will know that there is no truth in the things that they have been informed about you, but that you yourself also walk keeping the law."},{"v":25,"t":"But concerning the Gentiles who believe, we have written our decision that they should observe no such thing, except that they should keep themselves from food offered to idols, from blood, from strangled things, and from sexual immorality.”"},{"v":26,"t":"Then Paul took the men, and the next day purified himself and went with them into the temple, declaring the fulfillment of the days of purification, until the offering was offered for every one of them."},{"v":27,"t":"When the seven days were almost completed, the Jews from Asia, when they saw him in the temple, stirred up all the multitude and laid hands on him,"},{"v":28,"t":"crying out, “Men of Israel, help! This is the man who teaches all men everywhere against the people, and the law, and this place. Moreover, he also brought Greeks into the temple and has defiled this holy place!”"},{"v":29,"t":"For they had seen Trophimus the Ephesian, with him in the city, and they supposed that Paul had brought him into the temple."},{"v":30,"t":"All the city was moved and the people ran together. They seized Paul and dragged him out of the temple. Immediately the doors were shut."},{"v":31,"t":"As they were trying to kill him, news came up to the commanding officer of the regiment that all Jerusalem was in an uproar."},{"v":32,"t":"Immediately he took soldiers and centurions and ran down to them. They, when they saw the chief captain and the soldiers, stopped beating Paul."},{"v":33,"t":"Then the commanding officer came near, arrested him, commanded him to be bound with two chains, and inquired who he was and what he had done."},{"v":34,"t":"Some shouted one thing and some another, among the crowd. When he couldn’t find out the truth because of the noise, he commanded him to be brought into the barracks."},{"v":35,"t":"When he came to the stairs, he was carried by the soldiers because of the violence of the crowd;"},{"v":36,"t":"for the multitude of the people followed after, crying out, “Away with him!”"},{"v":37,"t":"As Paul was about to be brought into the barracks, he asked the commanding officer, “May I speak to you?” He said, “Do you know Greek?"},{"v":38,"t":"Aren’t you then the Egyptian who before these days stirred up to sedition and led out into the wilderness the four thousand men of the Assassins?”"},{"v":39,"t":"But Paul said, “I am a Jew from Tarsus in Cilicia, a citizen of no insignificant city. I beg you, allow me to speak to the people.”"},{"v":40,"t":"When he had given him permission, Paul, standing on the stairs, beckoned with his hand to the people. When there was a great silence, he spoke to them in the Hebrew language, saying,"}],"hr":[{"v":1,"t":"Pošto se otrgosmo od njih, zaplovismo. Jedreći ravno, stigosmo na Kos, a sutradan na Rod pa odande u Pataru."},{"v":2,"t":"Kad nađosmo lađu za Feniciju, popesmo se i otplovismo."},{"v":3,"t":"Kad bijasmo napomol Cipru, ostavismo ga slijeva jedreći prema Siriji. Pristadosmo u Tiru jer je ondje lađa imala iskrcati tovar."},{"v":4,"t":"Pronađosmo učenike i ostadosmo ondje sedam dana. Oni po Duhu nagovarahu Pavla da ne uzlazi u Jeruzalem."},{"v":5,"t":"Ali kad nam istekoše dani, ipak otputovasmo. Ispratiše nas svi, sa ženama i djecom, do izvan grada. Na žalu klekosmo i pomolismo se."},{"v":6,"t":"Pozdravismo se, popesmo se na lađu, a oni se vratiše kući."},{"v":7,"t":"Tako dovršismo plovidbu. Iz Tira stigosmo u Ptolemaidu. Pozdravili smo braću i ostali jedan dan u njih."},{"v":8,"t":"Sutradan otputovasmo i stigosmo u Cezareju. Uđosmo u kuću Filipa evanđelista, jednog od sedmorice, i ostadosmo kod njega."},{"v":9,"t":"On je imao četiri kćeri djevice koje su prorokovale."},{"v":10,"t":"Kako smo se zadržali mnogo dana, siđe iz Judeje neki prorok imenom Agab,"},{"v":11,"t":"dođe k nama, uze Pavlov pojas, sveza sebi noge i ruke te reče: “Ovo govori Duh Sveti: Čovjeka čiji je ovo pojas ovako će svezati Židovi u Jeruzalemu i predati u ruke pogana.”"},{"v":12,"t":"Kada smo to čuli, stadosmo mi i mještani zaklinjati Pavla da ne uzlazi u Jeruzalem."},{"v":13,"t":"Nato on odvrati: “Što plačete i parate mi srce? Ta spreman sam ne samo biti svezan nego i umrijeti u Jeruzalemu za ime Gospodina Isusa.”"},{"v":14,"t":"A kako se nije dao nagovoriti, ušutjesmo rekavši: “Gospodnja budi volja!”"},{"v":15,"t":"Nakon tih dana spremismo se i uzađosmo u Jeruzalem."},{"v":16,"t":"S nama pođoše i učenici iz Cezareje pa nas odvedoše k nekomu Mnasonu Cipraninu, starom učeniku, da u njega odsjednemo."},{"v":17,"t":"Kad stigosmo u Jeruzalem, primiše nas braća radosno."},{"v":18,"t":"Sutradan ode Pavao zajedno s nama k Jakovu. Nađoše se ondje i sve starješine."},{"v":19,"t":"Pošto ih pozdravi, stade im potanko izlagati što učini Bog među poganima po njegovoj službi."},{"v":20,"t":"Pošto su ga oni poslušali, dadoše slavu Bogu pa mu rekoše: “Vidiš, brate: deseci su tisuća Židova povjerovali i svi su revnitelji Zakona."},{"v":21,"t":"A o tebi im je dojavljeno da sve Židove koji su među poganima upućuješ na otpad od Mojsija učeći ih da ne obrezuju djece i ne žive po običajima."},{"v":22,"t":"Što dakle? Čut će svakako da si došao."},{"v":23,"t":"Učini stoga što ti kažemo. U nas su četiri čovjeka koji imaju zavjet."},{"v":24,"t":"Njih uzmi, s njima se zajedno posveti, plati za njih da se ošišaju pa će svi spoznati da nema ništa od onoga što im je o tebi dojavljeno, nego da si i ti na pravu putu i da opslužuješ Zakon."},{"v":25,"t":"A što se tiče pogana koji povjerovaše - poslali smo što odlučismo: da se klone mesa žrtvovana idolima, krvi, udavljenoga i bludništva.”"},{"v":26,"t":"Nato Pavao uze one ljude, sutradan se s njima zajedno posveti, uđe u Hram, oglasi svršetak dana posvećenja nakon kojih će se za svakoga od njih prinijeti prinos."},{"v":27,"t":"Kad se upravo navršavalo tih sedam dana, neki ga Židovi iz Azije opaze u Hramu, uzbune sav narod pa podignu na nj ruke"},{"v":28,"t":"vičući: “Izraelci, u pomoć! Evo čovjeka koji sve posvuda poučava protiv naroda, Zakona i ovoga mjesta pa je još i Grke uveo u Hram i oskvrnuo ovo sveto mjesto.”"},{"v":29,"t":"Jer prije su s njime u Gradu vidjeli Trofima Efežanina i mislili da je Pavao njega uveo u Hram."},{"v":30,"t":"Sav se grad uskomeša, nasta strka naroda. Pograbe Pavla i odvuku ga izvan Hrama pa odmah pozatvaraju vrata."},{"v":31,"t":"Dok su mu o glavi radili, dođe do tisućnika čete glas da je sav Jeruzalem uzavreo."},{"v":32,"t":"On odmah uze vojnike i satnike pa otrča dolje k njima. Oni pak kako ugledaše tisućnika i vojnike, prestadoše udarati Pavla."},{"v":33,"t":"Onda se tisućnik približi, uhvati ga, zapovjedi da ga okuju dvojim verigama pa stade ispitivati tko je i što je učinio."},{"v":34,"t":"Iz svjetine su jedni izvikivali ovo, drugi ono. Kako zbog graje nije mogao saznati ništa pouzdano, zapovjedi da se odvede u vojarnu."},{"v":35,"t":"Kad se Pavao pojavi na stubama, morali su ga vojnici nositi zbog silovitosti svjetine."},{"v":36,"t":"Jer mnoštvo je naroda išlo za njima i vikalo: “Smakni ga!”"},{"v":37,"t":"Upravo na ulazu u vojarnu reče Pavao tisućniku: “Smijem li nešto reći?” On ga upita: “Zar znaš grčki?"},{"v":38,"t":"Ti dakle nisi onaj Egipćanin koji je prije nekoliko dana pobunio i u pustinju odveo one četiri tisuće bodežara?”"},{"v":39,"t":"Pavao odvrati: “Ja sam Židov iz Tarza cilicijskoga, građanin grada znamenitoga. Molim te, dopusti mi progovoriti narodu.”"},{"v":40,"t":"Kad mu on dopusti, Pavao stojeći na stubama mahnu rukom narodu pa kad nasta velika tišina, prozbori hebrejskim jezikom:"}]},"22":{"fa":[{"v":1,"t":"«ای برادران عزیز و پدران، حجتی را که الان پیش شما می‌آورم بشنوید.»"},{"v":2,"t":"چون شنیدند که به زبان عبرانی با ایشان تکلم می‌کند، بیشتر خاموش شدند. پس گفت:"},{"v":3,"t":"«من مرد یهودی هستم، متولد طرسوس قیلیقیه، اما تربیت یافته بودم در این شهر درخدمت غمالائیل و در دقایق شریعت اجدادمتعلم شده، درباره خدا غیور می‌بودم، چنانکه همگی شما امروز می‌باشید."},{"v":4,"t":"و این طریقت را تابه قتل مزاحم می‌بودم به نوعی که مردان و زنان رابند نهاده، به زندان می‌انداختم،"},{"v":5,"t":"چنانکه رئیس کهنه و تمام اهل شورا به من شهادت می‌دهند که از ایشان نامه‌ها برای برادران گرفته، عازم دمشق شدم تا آنانی را نیز که در آنجا باشند قید کرده، به اورشلیم آورم تا سزا یابند."},{"v":6,"t":"و در اثنای راه، چون نزدیک به دمشق رسیدم، قریب به ظهر ناگاه نوری عظیم از آسمان گرد من درخشید."},{"v":7,"t":"پس بر زمین افتاده، هاتفی را شنیدم که به من می‌گوید: “ای شاول، ای شاول، چرا بر من جفا می‌کنی؟”"},{"v":8,"t":"من جواب دادم: “خداوندا تو کیستی؟” او مرا گفت: “من آن عیسی ناصری هستم که تو بر وی جفامی کنی.”"},{"v":9,"t":"و همراهان من نور را دیده، ترسان گشتند ولی آواز آن کس را که با من سخن گفت نشنیدند."},{"v":10,"t":"گفتم: “خداوندا چه کنم؟” خداوندمرا گفت: “برخاسته، به دمشق برو که در آنجا تو رامطلع خواهند ساخت از آنچه برایت مقرر است که بکنی.”"},{"v":11,"t":"پس چون از سطوت آن نور نابیناگشتم، رفقایم دست مرا گرفته، به دمشق رسانیدند."},{"v":12,"t":"آنگاه شخصی متقی بحسب شریعت، حنانیا نام که نزد همه یهودیان ساکن آنجا نیکنام بود،"},{"v":13,"t":"به نزد من آمده و ایستاده، به من گفت: “ای برادر شاول، بینا شو” که در همان ساعت بر وی نگریستم."},{"v":14,"t":"او گفت: “خدای پدران ما تو را برگزید تا اراده او را بدانی و آن عادل را ببینی و از زبانش سخنی بشنوی."},{"v":15,"t":"زیرااز آنچه دیده و شنیده‌ای نزد جمیع مردم شاهد براو خواهی شد."},{"v":16,"t":"و حال چرا تاخیر می‌نمایی؟ برخیز و تعمید بگیر و نام خداوند را خوانده، خود را از گناهانت غسل ده.”"},{"v":17,"t":"و چون به اورشلیم برگشته، در هیکل دعا می‌کردم، بیخودشدم."},{"v":18,"t":"پس او را دیدم که به من می‌گوید: “بشتاب و از اورشلیم به زودی روانه شو زیرا که شهادت تو را در حق من نخواهند پذیرفت.”"},{"v":19,"t":"من گفتم: “خداوندا، ایشان می‌دانند که من در هرکنیسه مومنین تو را حبس کرده، می‌زدم؛"},{"v":20,"t":"وهنگامی که خون شهید تو استیفان را می‌ریختند، من نیز ایستاده، رضا بدان دادم و جامه های قاتلان او را نگاه می‌داشتم.”"},{"v":21,"t":"او به من گفت: “روانه شوزیرا که من تو را به سوی امت های بعیدمی فرستم.»"},{"v":22,"t":"پس تا این سخن بدو گوش گرفتند؛ آنگاه آواز خود را بلند کرده، گفتند: «چنین شخص را ازروی زمین بردار که زنده ماندن او جایز نیست!»"},{"v":23,"t":"و چون غوغا نموده و جامه های خود راافشانده، خاک به هوا می‌ریختند،"},{"v":24,"t":"مین باشی فرمان داد تا او را به قلعه درآوردند و فرمود که اورا به تازیانه امتحان کنند تا بفهمد که به چه سبب اینقدر بر او فریاد می‌کردند."},{"v":25,"t":"و وقتی که او را به ریسمانها می‌بستند، پولس به یوزباشی‌ای که حاضر بود گفت: «آیا بر شما جایز است که مردی رومی را بی‌حجت هم تازیانه زنید؟»"},{"v":26,"t":"چون یوزباشی این را شنید، نزد مین باشی رفته، او راخبر داده، گفت: «چه می‌خواهی بکنی زیرا این شخص رومی است؟»"},{"v":27,"t":"پس مین باشی آمده، به وی گفت: «مرا بگو که تو رومی هستی؟» گفت: «بلی!»"},{"v":28,"t":"مین باشی جواب داد: «من این حقوق رابه مبلغی خطیر تحصیل کردم!» پولس گفت: «امامن در آن مولود شدم.»"},{"v":29,"t":"در ساعت آنانی که قصد تفتیش او داشتند، دست از او برداشتند ومین باشی ترسان گشت چون فهمید که رومی است از آن سبب که او را بسته بود."},{"v":30,"t":"بامدادان چون خواست درست بفهمد که یهودیان به چه علت مدعی او می‌باشند، او را از زندان بیرون آورده، فرمود تا روسای کهنه و تمامی اهل شوراحاضر شوند و پولس را پایین آورده، در میان ایشان برپا داشت."}],"en":[{"v":1,"t":"“Brothers and fathers, listen to the defense which I now make to you.”"},{"v":2,"t":"When they heard that he spoke to them in the Hebrew language, they were even more quiet. He said,"},{"v":3,"t":"“I am indeed a Jew, born in Tarsus of Cilicia, but brought up in this city at the feet of Gamaliel, instructed according to the strict tradition of the law of our fathers, being zealous for God, even as you all are today."},{"v":4,"t":"I persecuted this Way to the death, binding and delivering into prisons both men and women,"},{"v":5,"t":"as also the high priest and all the council of the elders testify, from whom also I received letters to the brothers, and traveled to Damascus to bring them also who were there to Jerusalem in bonds to be punished."},{"v":6,"t":"“As I made my journey and came close to Damascus, about noon suddenly a great light shone around me from the sky."},{"v":7,"t":"I fell to the ground and heard a voice saying to me, ‘Saul, Saul, why are you persecuting me?’"},{"v":8,"t":"I answered, ‘Who are you, Lord?’ He said to me, ‘I am Jesus of Nazareth, whom you persecute.’"},{"v":9,"t":"“Those who were with me indeed saw the light and were afraid, but they didn’t understand the voice of him who spoke to me."},{"v":10,"t":"I said, ‘What shall I do, Lord?’ The Lord said to me, ‘Arise, and go into Damascus. There you will be told about all things which are appointed for you to do.’"},{"v":11,"t":"When I couldn’t see for the glory of that light, being led by the hand of those who were with me, I came into Damascus."},{"v":12,"t":"“One Ananias, a devout man according to the law, well reported of by all the Jews who lived in Damascus,"},{"v":13,"t":"came to me, and standing by me said to me, ‘Brother Saul, receive your sight!’ In that very hour I looked up at him."},{"v":14,"t":"He said, ‘The God of our fathers has appointed you to know his will, and to see the Righteous One, and to hear a voice from his mouth."},{"v":15,"t":"For you will be a witness for him to all men of what you have seen and heard."},{"v":16,"t":"Now why do you wait? Arise, be baptized, and wash away your sins, calling on the name of the Lord.’"},{"v":17,"t":"“When I had returned to Jerusalem and while I prayed in the temple, I fell into a trance"},{"v":18,"t":"and saw him saying to me, ‘Hurry and get out of Jerusalem quickly, because they will not receive testimony concerning me from you.’"},{"v":19,"t":"I said, ‘Lord, they themselves know that I imprisoned and beat in every synagogue those who believed in you."},{"v":20,"t":"When the blood of Stephen, your witness, was shed, I also was standing by, consenting to his death, and guarding the cloaks of those who killed him.’"},{"v":21,"t":"“He said to me, ‘Depart, for I will send you out far from here to the Gentiles.’ ”"},{"v":22,"t":"They listened to him until he said that; then they lifted up their voice and said, “Rid the earth of this fellow, for he isn’t fit to live!”"},{"v":23,"t":"As they cried out, threw off their cloaks, and threw dust into the air,"},{"v":24,"t":"the commanding officer commanded him to be brought into the barracks, ordering him to be examined by scourging, that he might know for what crime they shouted against him like that."},{"v":25,"t":"When they had tied him up with straps, Paul asked the centurion who stood by, “Is it lawful for you to scourge a man who is a Roman, and not found guilty?”"},{"v":26,"t":"When the centurion heard it, he went to the commanding officer and told him, “Watch what you are about to do, for this man is a Roman!”"},{"v":27,"t":"The commanding officer came and asked him, “Tell me, are you a Roman?” He said, “Yes.”"},{"v":28,"t":"The commanding officer answered, “I bought my citizenship for a great price.” Paul said, “But I was born a Roman.”"},{"v":29,"t":"Immediately those who were about to examine him departed from him, and the commanding officer also was afraid when he realized that he was a Roman, because he had bound him."},{"v":30,"t":"But on the next day, desiring to know the truth about why he was accused by the Jews, he freed him from the bonds and commanded the chief priests and all the council to come together, and brought Paul down and set him before them."}],"hr":[{"v":1,"t":"“Braćo i oci, poslušajte što ću vam sad u svoju obranu reći.”"},{"v":2,"t":"Kad čuše da im govori hebrejskim jezikom, još većma utihnuše. On nastavi:"},{"v":3,"t":"“Ja sam Židov, rođen u Tarzu cilicijskom, ali odrastao u ovom gradu, do nogu Gamalielovih odgojen točno po otačkom Zakonu; bijah revnitelj Božji kao što ste svi vi još danas."},{"v":4,"t":"Ovaj sam Put na smrt progonio, u okove bacao i predavao u tamnice muževe i žene,"},{"v":5,"t":"kako mi to može posvjedočiti i veliki svećenik i sve starješinstvo. Od njih sam i pisma dobio za braću u Damasku pa se zaputio da i one ondje okovane dovedem u Jeruzalem da se kazne.”"},{"v":6,"t":"“Dok sam tako putovao i približavao se Damasku, s neba me oko podneva iznenada obasja svjetlost velika."},{"v":7,"t":"Sruših se na tlo i začuh glas što mi govoraše: 'Savle, Savle, zašto me progoniš?'"},{"v":8,"t":"Ja odgovorih: 'Tko si, Gospodine?' Reče mi: 'Ja sam Isus Nazarećanin koga ti progoniš.'"},{"v":9,"t":"Oni koji bijahu sa mnom svjetlost doduše primijetiše, ali ne čuše glasa Onoga koji mi govoraše."},{"v":10,"t":"Rekoh nato: 'Što mi je činiti, Gospodine?' Gospodin će mi: 'Ustani, pođi u Damask i ondje će ti se reći što ti je određeno učiniti.'"},{"v":11,"t":"Kako od sjaja one svjetlosti obnevidjeh, pratioci me povedoše za ruku te stigoh u Damask.”"},{"v":12,"t":"“Neki Ananija, čovjek po Zakonu pobožan i na dobru glasu u Židova ondje nastanjenih -"},{"v":13,"t":"dođe k meni, pristupi mi i reče: 'Savle, brate, progledaj!' I ja se u taj čas zagledah u nj."},{"v":14,"t":"A on će: 'Bog otaca naših predodredi te da upoznaš volju njegovu, da vidiš Pravednika i čuješ glas iz usta njegovih"},{"v":15,"t":"jer bit ćeš mu pred svim ljudima svjedokom onoga što si vidio i čuo."},{"v":16,"t":"I što sad oklijevaš? Ustani, krsti se i operi grijehe svoje, prizivljući Ime njegovo!'”"},{"v":17,"t":"“Pošto se vratih u Jeruzalem, dok sam se jednom molio u Hramu, padoh u zanos"},{"v":18,"t":"i vidjeh Gospodina gdje mi govori: 'Pohiti, žurno izađi iz Jeruzalema jer neće primiti tvoga svjedočanstva o meni.'"},{"v":19,"t":"Ja rekoh: 'Gospodine, oni znaju da sam ja u tamnice bacao i bičevao po sinagogama one koji vjeruju u te."},{"v":20,"t":"I dok se prolijevala krv Stjepana, svjedoka tvoga, i ja sam ondje stajao i odobravao te čuvao haljine onih koji ga ubijahu.'"},{"v":21,"t":"Nato mi reče: 'Pođi jer ću te poslati daleko k poganima!'"},{"v":22,"t":"Slušali su ga sve do te riječi, a tada podigoše glas: “Ukloni takva sa zemlje! Nije pravo da živi!”"},{"v":23,"t":"Kako oni stadoše bučiti, odbacivati haljine i vitlati prašinu u zrak,"},{"v":24,"t":"zapovjedi tisućnik da Pavla uvedu u vojarnu pa odredi da ga bičevima ispitaju kako bi doznao zašto tako viču protiv njega."},{"v":25,"t":"Kad ga remenjem rastegoše, reče on nazočnom satniku: “Rimskoga građanina, i još neosuđena, smijete bičevati?”"},{"v":26,"t":"Kad je to čuo satnik, priđe tisućniku i dojavi mu: “Što si to nakanio? Ovaj je čovjek Rimljanin!”"},{"v":27,"t":"Tisućnik tada priđe Pavlu pa mu reče: “Reci mi, jesi li Rimljanin!” On odvrati: “Da.”"},{"v":28,"t":"Tisućnik dometnu: “Ja stekoh to građanstvo za skupe novce.” Pavao nato reče: “Ja sam se pak s njim i rodio.”"},{"v":29,"t":"Brže stoga odstupe od njega oni koji su ga imali ispitivati. I tisućnik se preplaši kad sazna da je Pavao Rimljanin, a on ga bijaše okovao."},{"v":30,"t":"Sutradan pak kad je htio točno saznati za što ga Židovi optužuju, odriješi ga pa zapovjedi da se sastanu veliki svećenici i sve Vijeće te privede Pavla i postavi ga pred njih."}]},"23":{"fa":[{"v":1,"t":"پس پولس به اهل شورا نیک نگریسته، گفت: «ای برادران، من تا امروز با کمال ضمیر صالح در خدمت خدا رفتار کرده‌ام.»"},{"v":2,"t":"آنگاه حنانیا، رئیس کهنه، حاضران را فرمودتا به دهانش زنند."},{"v":3,"t":"پولس بدو گفت: «خدا تو راخواهد زد، ای دیوار سفیدشده! تو نشسته‌ای تامرا برحسب شریعت داوری کنی و به ضدشریعت حکم به زدنم می‌کنی؟»"},{"v":4,"t":"حاضران گفتند: «آیا رئیس کهنه خدا را دشنام می‌دهی؟»"},{"v":5,"t":"پولس گفت: «ای برادران، ندانستم که رئیس کهنه است، زیرا مکتوب است حاکم قوم خود رابد مگوی.»"},{"v":6,"t":"چون پولس فهمید که بعضی از صدوقیان وبعضی از فریسیانند، در مجلس ندا در‌داد که «ای برادران، من فریسی، پسر فریسی هستم و برای امید و قیامت مردگان از من بازپرس می‌شود.»"},{"v":7,"t":"چون این را گفت، در میان فریسیان و صدوقیان منازعه برپا شد و جماعت دو فرقه شدند،"},{"v":8,"t":"زیراکه صدوقیان منکر قیامت و ملائکه و ارواح هستند لیکن فریسیان قائل به هر دو."},{"v":9,"t":"پس غوغای عظیم برپا شد و کاتبان از فرقه فریسیان برخاسته مخاصمه نموده، می‌گفتند که «در این شخص هیچ بدی نیافته‌ایم و اگر روحی یا فرشته‌ای با او سخن گفته باشد با خدا جنگ نبایدنمود.»"},{"v":10,"t":"و چون منازعه زیادتر می‌شد، مین باشی ترسید که مبادا پولس را بدرند. پس فرمود تاسپاهیان پایین آمده، او را از میانشان برداشته، به قلعه درآوردند."},{"v":11,"t":"و در شب همان روز خداوند نزد او آمده، گفت: «ای پولس خاطر جمع باش زیرا چنانکه دراورشلیم در حق من شهادت دادی، همچنین بایددر روم نیز شهادت دهی.»"},{"v":12,"t":"و چون روز شد، یهودیان با یکدیگر عهدبسته، بر خویشتن لعن کردند که تا پولس رانکشند، نخورند و ننوشند."},{"v":13,"t":"و آنانی که درباره این، همقسم شدند، زیاده از چهل نفر بودند."},{"v":14,"t":"اینها نزد روسای کهنه و مشایخ رفته، گفتند: «بر خویشتن لعنت سخت کردیم که تا پولس رانکشیم چیزی نچشیم."},{"v":15,"t":"پس الان شما با اهل شورا، مین باشی را اعلام کنید که او را نزد شمابیاورد که گویا اراده دارید در احوال او نیکوترتحقیق نمایید؛ و ما حاضر هستیم که قبل ازرسیدنش او را بکشیم.»"},{"v":16,"t":"اما خواهرزاده پولس از کمین ایشان اطلاع یافته، رفت و به قلعه درآمده، پولس را آگاهانید."},{"v":17,"t":"پولس یکی ازیوزباشیان را طلبیده، گفت: «این جوان را نزدمین باشی ببر زیرا خبری دارد که به او بگوید.»"},{"v":18,"t":"پس او را برداشته، به حضور مین باشی رسانیده، گفت: «پولس زندانی مرا طلبیده، خواهش کرد که این جوان را به خدمت تو بیاورم، زیرا چیزی داردکه به تو عرض کند.»"},{"v":19,"t":"پس مین باشی دستش راگرفته، به خلوت برد و پرسید: «چه چیز است که می خواهی به من خبر دهی؟»"},{"v":20,"t":"عرض کرد: «یهودیان متفق شده‌اند که از تو خواهش کنند تاپولس را فردا به مجلس شورا درآوری که گویااراده دارند در حق او زیادتر تفتیش نمایند."},{"v":21,"t":"پس خواهش ایشان را اجابت مفرما زیرا که بیشتر از چهل نفر از ایشان در کمین وی‌اند و به سوگند عهد بسته‌اند که تا او را نکشند چیزی نخورند و نیاشامند و الان مستعد و منتظر وعده تو می‌باشند.»"},{"v":22,"t":"مین باشی آن جوان را مرخص فرموده، قدغن نمود که «به هیچ‌کس مگو که مرا ازاین راز مطلع ساختی.»"},{"v":23,"t":"پس دو نفر از یوزباشیان را طلبیده، فرمودکه «دویست سپاهی و هفتاد سوار و دویست نیزه‌دار در ساعت سوم از شب حاضر سازید تا به قیصریه بروند؛"},{"v":24,"t":"و مرکبی حاضر کنید تا پولس را سوار کرده، او را به سلامتی به نزد فیلکس والی برسانند.»"},{"v":25,"t":"و نامه‌ای بدین مضمون نوشت:"},{"v":26,"t":"«کلودیوس لیسیاس، به والی گرامی فیلکس سلام می‌رساند."},{"v":27,"t":"یهودیان این شخص را گرفته، قصد قتل او داشتند. پس با سپاه رفته، او را ازایشان گرفتم، چون دریافت کرده بودم که رومی است."},{"v":28,"t":"و چون خواستم بفهمم که به چه سبب بروی شکایت می‌کنند، او را به مجلس ایشان درآوردم."},{"v":29,"t":"پس یافتم که در مسائل شریعت خود از او شکایت می‌دارند، ولی هیچ شکوه‌ای مستوجب قتل یا بند نمی دارند."},{"v":30,"t":"و چون خبریافتم که یهودیان قصد کمین سازی برای او دارند، بی‌درنگ او را نزد تو فرستادم و مدعیان او را نیزفرمودم تا در حضور تو بر او ادعا نمایندوالسلام.»"},{"v":31,"t":"پس سپاهیان چنانکه مامور شدند، پولس را در شب برداشته، به انتیپاتریس رسانیدند."},{"v":32,"t":"و بامدادان سواران را گذاشته که با او بروند، خود به قلعه برگشتند."},{"v":33,"t":"و چون ایشان وارد قیصریه شدند، نامه را به والی سپردند و پولس را نیز نزد اوحاضر ساختند."},{"v":34,"t":"پس والی نامه را ملاحظه فرموده، پرسید که از کدام ولایت است. چون دانست که از قیلیقیه است،"},{"v":35,"t":"گفت: «چون مدعیان تو حاضر شوند، سخن تو را خواهم شنید.» و فرمود تا او را در سرای هیرودیس نگاه دارند."}],"en":[{"v":1,"t":"Paul, looking steadfastly at the council, said, “Brothers, I have lived before God in all good conscience until today.”"},{"v":2,"t":"The high priest, Ananias, commanded those who stood by him to strike him on the mouth."},{"v":3,"t":"Then Paul said to him, “God will strike you, you whitewashed wall! Do you sit to judge me according to the law, and command me to be struck contrary to the law?”"},{"v":4,"t":"Those who stood by said, “Do you malign God’s high priest?”"},{"v":5,"t":"Paul said, “I didn’t know, brothers, that he was high priest. For it is written, ‘You shall not speak evil of a ruler of your people.’”"},{"v":6,"t":"But when Paul perceived that the one part were Sadducees and the other Pharisees, he cried out in the council, “Men and brothers, I am a Pharisee, a son of Pharisees. Concerning the hope and resurrection of the dead I am being judged!”"},{"v":7,"t":"When he had said this, an argument arose between the Pharisees and Sadducees, and the crowd was divided."},{"v":8,"t":"For the Sadducees say that there is no resurrection, nor angel, nor spirit; but the Pharisees confess all of these."},{"v":9,"t":"A great clamor arose, and some of the scribes of the Pharisees’ part stood up, and contended, saying, “We find no evil in this man. But if a spirit or angel has spoken to him, let’s not fight against God!”"},{"v":10,"t":"When a great argument arose, the commanding officer, fearing that Paul would be torn in pieces by them, commanded the soldiers to go down and take him by force from among them and bring him into the barracks."},{"v":11,"t":"The following night, the Lord stood by him and said, “Cheer up, Paul, for as you have testified about me at Jerusalem, so you must testify also at Rome.”"},{"v":12,"t":"When it was day, some of the Jews banded together and bound themselves under a curse, saying that they would neither eat nor drink until they had killed Paul."},{"v":13,"t":"There were more than forty people who had made this conspiracy."},{"v":14,"t":"They came to the chief priests and the elders, and said, “We have bound ourselves under a great curse to taste nothing until we have killed Paul."},{"v":15,"t":"Now therefore, you with the council inform the commanding officer that he should bring him down to you tomorrow, as though you were going to judge his case more exactly. We are ready to kill him before he comes near.”"},{"v":16,"t":"But Paul’s sister’s son heard they were lying in wait, and he came and entered into the barracks and told Paul."},{"v":17,"t":"Paul summoned one of the centurions and said, “Bring this young man to the commanding officer, for he has something to tell him.”"},{"v":18,"t":"So he took him and brought him to the commanding officer and said, “Paul, the prisoner, summoned me and asked me to bring this young man to you. He has something to tell you.”"},{"v":19,"t":"The commanding officer took him by the hand, and going aside, asked him privately, “What is it that you have to tell me?”"},{"v":20,"t":"He said, “The Jews have agreed to ask you to bring Paul down to the council tomorrow, as though intending to inquire somewhat more accurately concerning him."},{"v":21,"t":"Therefore don’t yield to them, for more than forty men lie in wait for him, who have bound themselves under a curse to neither eat nor drink until they have killed him. Now they are ready, looking for the promise from you.”"},{"v":22,"t":"So the commanding officer let the young man go, charging him, “Tell no one that you have revealed these things to me.”"},{"v":23,"t":"He called to himself two of the centurions, and said, “Prepare two hundred soldiers to go as far as Caesarea, with seventy horsemen and two hundred men armed with spears, at the third hour of the night.”"},{"v":24,"t":"He asked them to provide mounts, that they might set Paul on one, and bring him safely to Felix the governor."},{"v":25,"t":"He wrote a letter like this:"},{"v":26,"t":"“Claudius Lysias to the most excellent governor Felix: Greetings."},{"v":27,"t":"“This man was seized by the Jews, and was about to be killed by them when I came with the soldiers and rescued him, having learned that he was a Roman."},{"v":28,"t":"Desiring to know the cause why they accused him, I brought him down to their council."},{"v":29,"t":"I found him to be accused about questions of their law, but not to be charged with anything worthy of death or of imprisonment."},{"v":30,"t":"When I was told that the Jews lay in wait for the man, I sent him to you immediately, charging his accusers also to bring their accusations against him before you. Farewell.”"},{"v":31,"t":"So the soldiers, carrying out their orders, took Paul and brought him by night to Antipatris."},{"v":32,"t":"But on the next day they left the horsemen to go with him, and returned to the barracks."},{"v":33,"t":"When they came to Caesarea and delivered the letter to the governor, they also presented Paul to him."},{"v":34,"t":"When the governor had read it, he asked what province he was from. When he understood that he was from Cilicia, he said,"},{"v":35,"t":"“I will hear you fully when your accusers also arrive.” He commanded that he be kept in Herod’s palace."}],"hr":[{"v":1,"t":"Pavao uprije pogled u Vijeće i reče: “Braćo, ja sam posve mirne savjesti živio pred Bogom sve do dana današnjega.”"},{"v":2,"t":"Nato veliki svećenik Ananija naredi onima što stajahu uza nj da ga udare po ustima."},{"v":3,"t":"Onda mu Pavao reče: “Udarit će Bog tebe, zide obijeljeni! Ti li sjediš da me po Zakonu sudiš, a protuzakonito zapovijedaš da me biju?”"},{"v":4,"t":"Oni što su ondje stajali rekoše nato: “Zar velikog svećenika Božjega da pogrđuješ?”"},{"v":5,"t":"Pavao odvrati: “Nisam znao, braćo, da je veliki svećenik. Ta pisano je: Glavara naroda svoga ne proklinji.”"},{"v":6,"t":"Pavao je znao da su oni dijelom saduceji, a dijelom farizeji pa povika u Vijeću: “Braćo, ja sam farizej, sin farizeja. Sudi mi se zbog nade, uskrsnuća mrtvih.”"},{"v":7,"t":"Tek što je on to rekao, nasta razmirica između farizeja i saduceja i mnoštvo se razdijeli."},{"v":8,"t":"Jer saduceji vele da nema uskrsnuća, ni anđela, ni duha, a farizeji sve to priznaju."},{"v":9,"t":"Nasta velika graja te ustadoše neki pismoznanci farizejske stranke i zaoštre boj govoreći: “Ništa zlo ne nalazimo na tom čovjeku! A što ako mu je duh govorio, ili anđeo?”"},{"v":10,"t":"Kad razmirica posta još većom, poboja se tisućnik da Pavla ne rastrgaju pa zapovjedi da vojska siđe, otme ga ispred njih i povede u vojarnu."},{"v":11,"t":"Iduće noći pristupi mu Gospodin i reče: “Hrabro samo! Jer kao što si za me svjedočio u Jeruzalemu tako treba da i u Rimu posvjedočiš!”"},{"v":12,"t":"Kad osvanu dan, skovaše Židovi urotu i zakleše se da neće ni jesti ni piti dok ne ubiju Pavla."},{"v":13,"t":"Bilo je više od četrdeset onih koji su skovali tu zavjeru."},{"v":14,"t":"Oni odu k velikim svećenicima i starješinama pa reknu: “Zakletvom se zaklesmo ništa ne okusiti dok ne ubijemo Pavla."},{"v":15,"t":"Stoga vi sada zajedno s Vijećem predočite tisućniku neka vam ga dovede kao da kanite točnije razaznati njegov slučaj. A mi smo spremni pogubiti ga prije negoli se i približi.”"},{"v":16,"t":"Ali sin Pavlove sestre doču za zavjeru, približi se i uđe u vojarnu dojaviti Pavlu."},{"v":17,"t":"Pavao pak pozove jednog satnika i reče mu: “Ovog mladića odvedi k tisućniku: ima mu nešto dojaviti.”"},{"v":18,"t":"On ga uze, odvede k tisućniku i reče mu: “Uznik me Pavao pozva i zaiska da ovog mladića privedem k tebi; ima ti nešto reći.”"},{"v":19,"t":"Tisućnik ga prihvati za ruku, povede nasamo pa ga upita: “Što mi imaš dojaviti?”"},{"v":20,"t":"“Židovi su se, reče on, dogovorili da te zamole da im sutra Pavla dovedeš u Vijeće kao da se kane točnije raspitati o njemu."},{"v":21,"t":"Ne vjeruj im! U zasjedi ga čeka više od četrdeset onih koji se zakleše da neće jesti ni piti dok ga ne smaknu. Već su spremni, samo čekaju tvoju privolu.”"},{"v":22,"t":"Tisućnik onda otpusti mladića i zapovjedi mu: “Nikomu ne kazuj da si mi to dojavio.”"},{"v":23,"t":"Zatim dozva dva satnika i reče im: “Pripravite dvjesta vojnika, sedamdeset konjanika i dvjesta strijelaca da nakon treće noćne ure pođu u Cezareju."},{"v":24,"t":"Neka se pripravi živina na koju će se posaditi Pavao te živ i zdrav dovesti k upravitelju Feliksu.”"},{"v":25,"t":"Napisa i pismo ovoga sadržaja:"},{"v":26,"t":"“Klaudije Lizija vrlom upravitelju Feliksu - pozdrav!"},{"v":27,"t":"Ovoga čovjeka Židovi uhvatiše i tek što ga ne smakoše kadli s vojskom pritrčah i istrgoh im ga kada doznah da je Rimljanin."},{"v":28,"t":"Htjedoh saznati za što ga okrivljuju pa ga dovedoh u njihovo Vijeće."},{"v":29,"t":"Utvrdih da ga okrivljuju za nešto prijeporno u njihovu zakonu i da nema nikakve krivnje kojom bi zaslužio smrt ili okove."},{"v":30,"t":"Kad mi pak dojaviše da su protiv njega skovali zavjeru, poslah ga k tebi, a tužitelje uputih neka se tebi obrate protiv njega.”"},{"v":31,"t":"Vojnici dakle, po primljenoj naredbi uzeše Pavla i odvedoše ga noću u Antipatridu."},{"v":32,"t":"Sutradan ostave konjanike da s njime pođu dalje, a oni se vratiše u vojarnu."},{"v":33,"t":"Kad konjanici stigoše u Cezareju, uručiše upravitelju pismo i privedoše mu Pavla."},{"v":34,"t":"Pošto upravitelj pročita pismo, zapita iz koje je pokrajine. Kad sazna da je iz Cilicije:"},{"v":35,"t":"“Saslušat ću te, reče, kad pristignu i tužitelji tvoji.” Onda zapovjedi čuvati ga u dvoru Herodovu."}]},"24":{"fa":[{"v":1,"t":"و بعد از پنج روز، حنانیای رئیس کهنه با مشایخ و خطیبی ترتلس نام رسیدندو شکایت از پولس نزد والی آوردند."},{"v":2,"t":"و چون اورا احضار فرمود، ترتلس آغاز ادعا نموده، گفت: چون از وجود تو در آسایش کامل هستیم واحسانات عظیمه از تدابیر تو بدین قوم رسیده است، ای فیلکس گرامی،"},{"v":3,"t":"در هر جا و در هروقت این را در کمال شکرگذاری می‌پذیریم."},{"v":4,"t":"ولیکن تا تو را زیاده مصدع نشوم، مستدعی هستم که از راه نوازش مختصر عرض ما را بشنوی."},{"v":5,"t":"زیرا که این شخص را مفسد و فتنه انگیز یافته‌ایم در میان همه یهودیان ساکن ربع مسکون و ازپیشوایان بدعت نصاری."},{"v":6,"t":"و چون او خواست هیکل را ملوث سازد، او را گرفته، اراده داشتیم که به قانون شریعت خود بر او داوری نماییم."},{"v":7,"t":"ولی لیسیاس مین باشی آمده، او را به زور بسیار ازدستهای ما بیرون آورد،"},{"v":8,"t":"و فرمود تا مدعیانش نزد تو حاضر شوند؛ و از او بعد از امتحان می‌توانی دانست حقیقت همه این اموری که ما براو ادعا می‌کنیم.»"},{"v":9,"t":"و یهودیان نیز با او متفق شده گفتند که چنین است."},{"v":10,"t":"چون والی به پولس اشاره نمود که سخن بگوید، او جواب داد: «از آن رو که می‌دانم سالهای بسیار است که تو حاکم این قوم می‌باشی، به خشنودی وافر حجت درباره خود می‌آورم."},{"v":11,"t":"زیرا تو می‌توانی دانست که زیاده از دوازده روز نیست که من برای عبادت به اورشلیم رفتم،"},{"v":12,"t":"و مرا نیافتند که در هیکل با کسی مباحثه کنم ونه در کنایس یا شهر‌که خلق را به شورش آورم."},{"v":13,"t":"و هم آنچه الان بر من ادعا می‌کنند، نمی تواننداثبات نمایند."},{"v":14,"t":"لیکن این را نزد تو اقرار می‌کنم که به طریقتی که بدعت می‌گویند، خدای پدران را عبادت می‌کنم و به آنچه در تورات و انبیامکتوب است معتقدم،"},{"v":15,"t":"و به خدا امیدوارم چنانکه ایشان نیز قبول دارند که قیامت مردگان ازعادلان و ظالمان نیز خواهد شد."},{"v":16,"t":"و خود را دراین امر ریاضت می‌دهم تا پیوسته ضمیر خود رابه سوی خدا و مردم بی‌لغزش نگاه دارم."},{"v":17,"t":"و بعداز سالهای بسیار آمدم تا صدقات و هدایا برای قوم خود بیاورم."},{"v":18,"t":"و در این امور چند نفر ازیهودیان آسیا مرا در هیکل مطهر یافتند بدون هنگامه یا شورشی."},{"v":19,"t":"و ایشان می‌بایست نیز دراینجا نزد تو حاضر شوند تا اگر حرفی بر من دارندادعا کنند."},{"v":20,"t":"یا اینان خود بگویند اگر گناهی ازمن یافتند وقتی که در حضور اهل شورا ایستاده بودم،"},{"v":21,"t":"مگر آن یک سخن که در میان ایشان ایستاده، بدان ندا کردم که درباره قیامت مردگان ازمن امروز پیش شما بازپرس می‌شود.»"},{"v":22,"t":"آنگاه فیلکس چون از طریقت نیکوترآگاهی داشت، امر ایشان را تاخیر انداخته، گفت: «چون لیسیاس مین باشی آید، حقیقت امر شما را دریافت خواهم کرد.»"},{"v":23,"t":"پس یوزباشی را فرمان داد تا پولس را نگاه دارد و او را آزادی دهد واحدی از خویشانش را از خدمت و ملاقات اومنع نکند."},{"v":24,"t":"و بعد از روزی چند فیلکس با زوجه خود درسلا که زنی یهودی بود، آمده پولس راطلبیده، سخن او را درباره ایمان مسیح شنید."},{"v":25,"t":"وچون او درباره عدالت و پرهیزکاری وداوری آینده خطاب می‌کرد، فیلکس ترسان گشته، جواب داد که «الحال برو چون فرصت کنم تو راباز خواهم خواند.»"},{"v":26,"t":"و نیز امید می‌داشت که پولس او را نقدی بدهد تا او را آزاد سازد و از این جهت مکرر وی را خواسته، با او گفتگو می‌کرد."},{"v":27,"t":"اما بعد از انقضای دو سال، پورکیوس فستوس، خلیفه ولایت فیلکس شد و فیلکس چون خواست بر یهود منت نهد، پولس را در زندان گذاشت."}],"en":[{"v":1,"t":"After five days, the high priest, Ananias, came down with certain elders and an orator, one Tertullus. They informed the governor against Paul."},{"v":2,"t":"When he was called, Tertullus began to accuse him, saying, “Seeing that by you we enjoy much peace, and that prosperity is coming to this nation by your foresight,"},{"v":3,"t":"we accept it in all ways and in all places, most excellent Felix, with all thankfulness."},{"v":4,"t":"But that I don’t delay you, I entreat you to bear with us and hear a few words."},{"v":5,"t":"For we have found this man to be a plague, an instigator of insurrections among all the Jews throughout the world, and a ringleader of the sect of the Nazarenes."},{"v":6,"t":"He even tried to profane the temple, and we arrested him."},{"v":8,"t":"By examining him yourself you may ascertain all these things of which we accuse him.”"},{"v":9,"t":"The Jews also joined in the attack, affirming that these things were so."},{"v":10,"t":"When the governor had beckoned to him to speak, Paul answered, “Because I know that you have been a judge of this nation for many years, I cheerfully make my defense,"},{"v":11,"t":"seeing that you can verify that it is not more than twelve days since I went up to worship at Jerusalem."},{"v":12,"t":"In the temple they didn’t find me disputing with anyone or stirring up a crowd, either in the synagogues or in the city."},{"v":13,"t":"Nor can they prove to you the things of which they now accuse me."},{"v":14,"t":"But this I confess to you, that according to the Way, which they call a sect, so I serve the God of our fathers, believing all things which are according to the law, and which are written in the prophets;"},{"v":15,"t":"having hope toward God, which these also themselves look for, that there will be a resurrection of the dead, both of the just and unjust."},{"v":16,"t":"In this I also practice always having a conscience void of offense toward God and men."},{"v":17,"t":"Now after some years, I came to bring gifts for the needy to my nation, and offerings;"},{"v":18,"t":"amid which certain Jews from Asia found me purified in the temple, not with a mob, nor with turmoil."},{"v":19,"t":"They ought to have been here before you and to make accusation if they had anything against me."},{"v":20,"t":"Or else let these men themselves say what injustice they found in me when I stood before the council,"},{"v":21,"t":"unless it is for this one thing that I cried standing among them, ‘Concerning the resurrection of the dead I am being judged before you today!’”"},{"v":22,"t":"But Felix, having more exact knowledge concerning the Way, deferred them, saying, “When Lysias, the commanding officer, comes down, I will decide your case.”"},{"v":23,"t":"He ordered the centurion that Paul should be kept in custody and should have some privileges, and not to forbid any of his friends to serve him or to visit him."},{"v":24,"t":"After some days, Felix came with Drusilla his wife, who was a Jewess, and sent for Paul and heard him concerning the faith in Christ Jesus."},{"v":25,"t":"As he reasoned about righteousness, self-control, and the judgment to come, Felix was terrified, and answered, “Go your way for this time, and when it is convenient for me, I will summon you.”"},{"v":26,"t":"Meanwhile, he also hoped that money would be given to him by Paul, that he might release him. Therefore also he sent for him more often and talked with him."},{"v":27,"t":"But when two years were fulfilled, Felix was succeeded by Porcius Festus, and desiring to gain favor with the Jews, Felix left Paul in bonds."}],"hr":[{"v":1,"t":"Nakon pet dana siđe veliki svećenik Ananija s nekim starješinama i odvjetnikom, nekim Tertulom te izniješe upravitelju tužbu protiv Pavla."},{"v":2,"t":"Pošto dozvaše Pavla, poče ga Tertul optuživati: “Veliki mir što ga po tebi, vrli Felikse, uživamo i boljitak što tvojom providnošću narodu ovomu nastaje,"},{"v":3,"t":"u svemu i posvuda primamo sa svom zahvalnošću."},{"v":4,"t":"Ali, da ti dulje ne dodijavam, molim te da nas u svojoj blagonaklonosti ukratko poslušaš."},{"v":5,"t":"Utvrdismo da je ovaj čovjek kuga, da pokreće bune među svim Židovima po svijetu, da je kolovođa nazaretske sljedbe,"},{"v":6,"t":"da je čak i Hram pokušao oskvrnuti pa ga uhitismo."},{"v":7,"t":"#"},{"v":8,"t":"Od njega, ako ga o svemu tomu ispitaš, možeš saznati za što ga mi optužujemo.”"},{"v":9,"t":"Podržaše ga i Židovi tvrdeći da je tako."},{"v":10,"t":"Nato Pavao odvrati pošto mu upravitelj kimnu da govori: “Kako znam da si već mnogo godina sudac narodu ovomu, mirne se duše branim."},{"v":11,"t":"Ta možeš se osvjedočiti da nema više od dvanaest dana otkad uzađoh u Jeruzalem da se poklonim."},{"v":12,"t":"A nisu me našli ni u Hramu da s kim raspravljam ili bunu podižem, ni u sinagogama, ni po gradu."},{"v":13,"t":"I ne mogu ti dokazati ono za što me sada optužuju.”"},{"v":14,"t":"“Jamčim ti, naprotiv, ovo: Putom koji nazivaju sljedbom služim otačkom Bogu vjerujući u sve što je u Zakonu i u Prorocima napisano,"},{"v":15,"t":"uzdajući se u Boga da će uskrsnuti pravednici i nepravednici, što oni i sami očekuju."},{"v":16,"t":"Zato se i ja trudim uvijek imati savjest besprijekornu pred Bogom i pred ljudima.”"},{"v":17,"t":"“Nakon više godina dođoh da donesem milostinju za svoj narod i prinose;"},{"v":18,"t":"dok sam ih prinosio, nađoše me posvećena u Hramu, a ne sa svjetinom ni u metežu."},{"v":19,"t":"Ali neki Židovi iz Azije - da, trebalo bi da se oni pojave pred tobom i optuže me ako što imaju protiv mene."},{"v":20,"t":"Ili neka ovi sami kažu: koji su zločin na meni našli kad sam stajao pred Vijećem,"},{"v":21,"t":"osim možda one jedne riječi koju doviknuh među njima stojeći: Zbog uskrsnuća mrtvih sudi mi se danas pred vama!”"},{"v":22,"t":"Nato Feliks, koji je točno znao sve o ovom Putu, odgodi njihovu parnicu rekavši: “Kada dođe tisućnik Lizija, riješit ću vaš spor.”"},{"v":23,"t":"Satniku pak naredi da se Pavao čuva, ali da uživa olakšice i da se nikomu od njegovih ne brani posluživati ga."},{"v":24,"t":"Nakon nekoliko dana stigne i Feliks sa svojom ženom Druzilom koja bijaše Židovka; posla po Pavla i posluša ga o vjeri u Isusa Krista."},{"v":25,"t":"Kad Pavao stade raspravljati o pravednosti, uzdržljivosti i budućem Sudu, Feliks uplašen reče: “Zasad idi, a kad nađem vremena, pozvat ću te.”"},{"v":26,"t":"Ujedno se nadao da će mu Pavao dati novaca. Zato ga je češće pozivao i s njim razgovarao."},{"v":27,"t":"Nakon dvije godine dobi Feliks za nasljednika Porcija Festa. Hoteći ugoditi Židovima, ostavi Feliks Pavla u okovima."}]},"25":{"fa":[{"v":1,"t":"پس چون فستوس به ولایت خودرسید، بعد از سه روز از قیصریه به اورشلیم رفت."},{"v":2,"t":"و رئیس کهنه و اکابر یهود نزد اوبر پولس ادعا کردند و بدو التماس نموده،"},{"v":3,"t":"منتی بر وی خواستند تا او را به اورشلیم بفرستد و درکمین بودند که او را در راه بکشند."},{"v":4,"t":"اما فستوس جواب داد که «پولس را باید در قیصریه نگاه داشت»، زیرا خود اراده داشت به زودی آنجابرود."},{"v":5,"t":"و گفت: «پس کسانی از شما که می‌توانندهمراه بیایند تا اگر چیزی در این شخص یافت شود، بر او ادعا نمایند.»"},{"v":6,"t":"و چون بیشتر از ده روز در میان ایشان توقف کرده بود، به قیصریه آمد و بامدادان بر مسندحکومت برآمده، فرمود تا پولس را حاضر سازند."},{"v":7,"t":"چون او حاضر شد، یهودیانی که از اورشلیم آمده بودند، به گرد او ایستاده، شکایتهای بسیار وگران بر پولس آوردند ولی اثبات نتوانستند کرد."},{"v":8,"t":"او جواب داد که «نه به شریعت یهود و نه به هیکل و نه به قیصر هیچ گناه کرده‌ام.»"},{"v":9,"t":"اما چون فستوس خواست بر یهود منت نهد، در جواب پولس گفت: «آیا می‌خواهی به اورشلیم آیی تا درآنجا در این امور به حضور من حکم شود؟»"},{"v":10,"t":"پولس گفت: «در محکمه قیصر ایستاده‌ام که درآنجا می‌باید محاکمه من بشود. به یهود هیچ ظلمی نکرده‌ام، چنانکه تو نیز نیکو می‌دانی."},{"v":11,"t":"پس هر گاه ظلمی یا عملی مستوجب قتل کرده باشم، از مردن دریغ ندارم. لیکن اگر هیچ‌یک ازاین شکایتهایی که اینها بر من می‌آورند اصلی ندارد، کسی نمی تواند مرا به ایشان سپارد. به قیصر رفع دعوی می‌کنم.»"},{"v":12,"t":"آنگاه فستوس بعداز مکالمه با اهل شورا جواب داد: «آیا به قیصررفع دعوی کردی؟ به حضور قیصر خواهی رفت.»"},{"v":13,"t":"و بعد از مرور ایام چند، اغریپاس پادشاه وبرنیکی برای تحیت فستوس به قیصریه آمدند."},{"v":14,"t":"و چون روزی بسیار در آنجا توقف نمودند، فستوس برای پادشاه، مقدمه پولس را بیان کرده، گفت: «مردی است که فیلکس او را در بند گذاشته است،"},{"v":15,"t":"که درباره او وقتی که به اورشلیم آمدم، روسای کهنه و مشایخ یهود مرا خبر دادند وخواهش نمودند که بر او داوری شود."},{"v":16,"t":"درجواب ایشان گفتم که رومیان را رسم نیست که احدی را بسپارند قبل از آنکه مدعی علیه مدعیان خود را روبرو شود و او را فرصت دهند که ادعای ایشان را جواب گوید."},{"v":17,"t":"پس چون ایشان دراینجا جمع شدند، بی‌درنگ در روز دوم بر مسندنشسته، فرمودم تا آن شخص را حاضر کردند."},{"v":18,"t":"و مدعیانش برپا ایستاده، از آنچه من گمان می‌بردم هیچ ادعا بر وی نیاوردند."},{"v":19,"t":"بلکه مساله‌ای چند بر او ایراد کردند درباره مذهب خود و در حق عیسی نامی که مرده است و پولس می‌گوید که او زنده است."},{"v":20,"t":"و چون من در این‌گونه مسایل شک داشتم، از او پرسیدم که “آیامی خواهی به اورشلیم بروی تا در آنجا این مقدمه فیصل پذیرد؟”"},{"v":21,"t":"ولی چون پولس رفع دعوی کرد که برای محاکمه اوغسطس محفوظ ماند، فرمان دادم که او را نگاه بدارند تا او را به حضورقیصر روانه نمایم.»"},{"v":22,"t":"اغریپاس به فستوس گفت: «من نیزمی خواهم این شخص را بشنوم.» گفت: «فردا اورا خواهی شنید.»"},{"v":23,"t":"پس بامدادان چون اغریپاس و برنیکی باحشمتی عظیم آمدند و به دارالاستماع بامین باشیان و بزرگان شهر داخل شدند، به فرمان فستوس پولس را حاضر ساختند."},{"v":24,"t":"آنگاه فستوس گفت: «ای اغریپاس پادشاه، و‌ای همه مردمانی که نزد ما حضور دارید، این شخص رامی بینید که درباره او تمامی جماعت یهود چه دراورشلیم و چه در اینجا فریاد کرده، از من خواهش نمودند که دیگر نباید زیست کند."},{"v":25,"t":"ولیکن چون من دریافتم که او هیچ عملی مستوجب قتل نکرده است و خود به اوغسطس رفع دعوی کرد، اراده کردم که او را بفرستم."},{"v":26,"t":"و چون چیزی درست ندارم که درباره او به خداوندگار مرقوم دارم، از این جهت او را نزد شما و علی الخصوص در حضور تو‌ای اغریپاس پادشاه آوردم تا بعد از تفحص شاید چیزی یافته بنگارم."},{"v":27,"t":"زیرا مراخلاف عقل می‌نماید که اسیری را بفرستم وشکایتهایی که بر اوست معروض ندارم.»"}],"en":[{"v":1,"t":"Festus therefore, having come into the province, after three days went up to Jerusalem from Caesarea."},{"v":2,"t":"Then the high priest and the principal men of the Jews informed him against Paul, and they begged him,"},{"v":3,"t":"asking a favor against him, that he would summon him to Jerusalem, plotting to kill him on the way."},{"v":4,"t":"However Festus answered that Paul should be kept in custody at Caesarea, and that he himself was about to depart shortly."},{"v":5,"t":"“Let them therefore”, he said, “that are in power among you go down with me, and if there is anything wrong in the man, let them accuse him.”"},{"v":6,"t":"When he had stayed among them more than ten days, he went down to Caesarea, and on the next day he sat on the judgment seat, and commanded Paul to be brought."},{"v":7,"t":"When he had come, the Jews who had come down from Jerusalem stood around him, bringing against him many and grievous charges which they could not prove,"},{"v":8,"t":"while he said in his defense, “Neither against the law of the Jews, nor against the temple, nor against Caesar, have I sinned at all.”"},{"v":9,"t":"But Festus, desiring to gain favor with the Jews, answered Paul and said, “Are you willing to go up to Jerusalem and be judged by me there concerning these things?”"},{"v":10,"t":"But Paul said, “I am standing before Caesar’s judgment seat, where I ought to be tried. I have done no wrong to the Jews, as you also know very well."},{"v":11,"t":"For if I have done wrong and have committed anything worthy of death, I don’t refuse to die; but if none of those things is true that they accuse me of, no one can give me up to them. I appeal to Caesar!”"},{"v":12,"t":"Then Festus, when he had conferred with the council, answered, “You have appealed to Caesar. To Caesar you shall go.”"},{"v":13,"t":"Now when some days had passed, King Agrippa and Bernice arrived at Caesarea and greeted Festus."},{"v":14,"t":"As he stayed there many days, Festus laid Paul’s case before the king, saying, “There is a certain man left a prisoner by Felix;"},{"v":15,"t":"about whom, when I was at Jerusalem, the chief priests and the elders of the Jews informed me, asking for a sentence against him."},{"v":16,"t":"I answered them that it is not the custom of the Romans to give up any man to destruction before the accused has met the accusers face to face and has had opportunity to make his defense concerning the matter laid against him."},{"v":17,"t":"When therefore they had come together here, I didn’t delay, but on the next day sat on the judgment seat and commanded the man to be brought."},{"v":18,"t":"When the accusers stood up, they brought no charges against him of such things as I supposed;"},{"v":19,"t":"but had certain questions against him about their own religion and about one Jesus, who was dead, whom Paul affirmed to be alive."},{"v":20,"t":"Being perplexed how to inquire concerning these things, I asked whether he was willing to go to Jerusalem and there be judged concerning these matters."},{"v":21,"t":"But when Paul had appealed to be kept for the decision of the emperor, I commanded him to be kept until I could send him to Caesar.”"},{"v":22,"t":"Agrippa said to Festus, “I also would like to hear the man myself.” “Tomorrow,” he said, “you shall hear him.”"},{"v":23,"t":"So on the next day, when Agrippa and Bernice had come with great pomp, and they had entered into the place of hearing with the commanding officers and the principal men of the city, at the command of Festus, Paul was brought in."},{"v":24,"t":"Festus said, “King Agrippa, and all men who are here present with us, you see this man about whom all the multitude of the Jews petitioned me, both at Jerusalem and here, crying that he ought not to live any longer."},{"v":25,"t":"But when I found that he had committed nothing worthy of death, and as he himself appealed to the emperor, I determined to send him,"},{"v":26,"t":"of whom I have no certain thing to write to my lord. Therefore I have brought him out before you, and especially before you, King Agrippa, that, after examination I may have something to write."},{"v":27,"t":"For it seems to me unreasonable, in sending a prisoner, not to also specify the charges against him.”"}],"hr":[{"v":1,"t":"Fest dakle tri dana nakon dolaska u provinciju uziđe iz Cezareje u Jeruzalem."},{"v":2,"t":"Veliki mu svećenici i prvaci židovski izniješe tužbu protiv Pavla te ga zaklinjahu"},{"v":3,"t":"ištući milost protiv Pavla: da ga pošalje u Jeruzalem. Jer spremali su zasjedu da ga putom smaknu."},{"v":4,"t":"Ali Fest odvrati kako Pavao treba da ostane zatvoren u Cezareji, a i on da će uskoro onamo."},{"v":5,"t":"“Ovlašteni dakle među vama, reče, neka sa mnom siđu pa ako na tom čovjeku ima krivnje, neka ga tuže.”"},{"v":6,"t":"Pošto se u njih zadrži najviše osam ili deset dana, siđe u Cezareju. Sutradan sjede na sudačku stolicu i zapovjedi da se dovede Pavao."},{"v":7,"t":"Kad se on pojavi, okružiše ga Židovi koji su sišli iz Jeruzalema i izniješe protiv njega mnoge i teške optužbe kojih ne mogahu dokazati."},{"v":8,"t":"Pavao se branio: “Ničim se nisam ogriješio ni o židovski Zakon, ni o Hram, ni o cara.”"},{"v":9,"t":"Nato Fest hoteći ugoditi Židovima, odvrati Pavlu: “Hoćeš li u Jeruzalem da ti se ondje za to sudi preda mnom?”"},{"v":10,"t":"A Pavao će: “Stojim pred sudom carevim, gdje treba da mi se sudi. Židovima ništa ne skrivih, kao što i ti veoma dobro znaš."},{"v":11,"t":"Ako sam pak doista što skrivio i učinio štogod što zavređuje smrt, ne izmičem smrti; ako li pak ne stoji ono za što me ovi tuže, nitko me ne može njima izručiti. Na cara se prizivljem!”"},{"v":12,"t":"Tada se Fest posavjetova s vijećem pa odgovori: “Na cara si se prizvao, pred cara ćeš ići!”"},{"v":13,"t":"Nekoliko dana poslije dođu kralj Agripa i Berenika u Cezareju da pozdrave Festa."},{"v":14,"t":"Kako se ondje zadržaše nekoliko dana, izloži Fest kralju to o Pavlu: “Ima neki čovjek, reče, što ga je Feliks ostavio uznikom."},{"v":15,"t":"Kad bijah u Jeruzalemu, izniješe veliki svećenici i starješine protiv njega tužbu i zatražiše osudu."},{"v":16,"t":"Odgovorih im da u Rimljana nije običaj izručivati kojega čovjeka prije negoli se, optužen, suoči s tužiteljima i dobije prigodu da se brani od optužbe."},{"v":17,"t":"Pošto zajedno dođosmo ovamo, bez ikakva odgađanja sjedoh ja sutradan na sudačku stolicu i zapovjedih dovesti toga čovjeka."},{"v":18,"t":"Tužitelji ga okružiše, ali ne izniješe tužbe ni za jedno od zlodjela koja sam ja naslućivao,"},{"v":19,"t":"nego su protiv njega imali nešto prijeporno o svojoj vjeri i o nekom Isusu koji je umro, a Pavao tvrdi da je živ."},{"v":20,"t":"Ne snalazeći se u takvoj raspravi, upitah bi li htio u Jeruzalem da mu se ondje za to sudi."},{"v":21,"t":"Budući da se Pavao prizivom podložio presudi njegova Veličanstva, zapovjedih da ga čuvaju dok ga ne pošaljem caru.”"},{"v":22,"t":"Na to će Agripa Festu: “Htio bih i ja čuti toga čovjeka.” “Sutra ćeš ga, reče, čuti.”"},{"v":23,"t":"Sutradan dakle dođu Agripa i Berenika s velikim sjajem te uđu u dvoranu zajedno s tisućnicima i najuglednijim gradskim muževima. Kad na zapovijed Festovu dovedu Pavla,"},{"v":24,"t":"reče Fest: “Agripa, kralju, i vi svi ovdje s nama nazočni, gledajte ovoga čovjeka! Zbog njega me sav narod židovski salijetao i u Jeruzalemu i ovdje vičući da on ne smije više živjeti."},{"v":25,"t":"Ali ja nađoh da nije učinio ništa čime bi zaslužio smrt pa kad se on sam prizvao na njegovo Veličanstvo, odlučih poslati mu ga."},{"v":26,"t":"Ja nemam ništa pouzdano o njemu napisati Gospodaru. Zato ga izvedoh pred vas, ponajpače preda te, kralju Agripa, da bih nakon ove istrage imao što napisati."},{"v":27,"t":"Čini mi se doista besmislenim poslati uznika, a ne naznačiti optužbu protiv njega.”"}]},"26":{"fa":[{"v":1,"t":"اغریپاس به پولس گفت: «مرخصی که کیفیت خود را بگویی.»"},{"v":2,"t":"که «ای اغریپاس پادشاه، سعادت خود را در این می‌دانم که امروز درحضور تو حجت بیاورم، درباره همه شکایتهایی که یهود از من می‌دارند."},{"v":3,"t":"خصوص چون تو درهمه رسوم و مسایل یهود عالم هستی، پس از تومستدعی آنم که تحمل فرموده، مرا بشنوی."},{"v":4,"t":"رفتار مرا از جوانی چونکه از ابتدا در میان قوم خود در اورشلیم بسر می‌بردم، تمامی یهودمی دانند"},{"v":5,"t":"و مرا از اول می‌شناسند هر گاه بخواهند شهادت دهند که به قانون پارساترین فرقه دین خود فریسی می‌بودم."},{"v":6,"t":"والحال به‌سبب امید آن وعده‌ای که خدا به اجداد ما داد، بر من ادعا می‌کنند."},{"v":7,"t":"و حال آنکه دوازده سبط ماشبانه‌روز بجد و جهد عبادت می‌کنند محض امید تحصیل همین وعده که بجهت همین امید، ای اغریپاس پادشاه، یهود بر من ادعا می‌کنند."},{"v":8,"t":"«شما چرا محال می‌پندارید که خدا مردگان را برخیزاند؟"},{"v":9,"t":"من هم در خاطر خود می‌پنداشتم که به نام عیسی ناصری مخالفت بسیار کردن واجب است،"},{"v":10,"t":"چنانکه در اورشلیم هم کردم واز روسای کهنه قدرت یافته، بسیاری از مقدسین را در زندان حبس می‌کردم و چون ایشان را می کشتند، در فتوا شریک می‌بودم."},{"v":11,"t":"و در همه کنایس بارها ایشان را زحمت رسانیده، مجبورمی ساختم که کفر گویند و بر ایشان به شدت دیوانه گشته تا شهرهای بعید تعاقب می‌کردم."},{"v":12,"t":"در این میان هنگامی که با قدرت و اجازت ازروسای کهنه به دمشق می‌رفتم،"},{"v":13,"t":"در راه، ای پادشاه، در وقت ظهر نوری را از آسمان دیدم، درخشنده تر از خورشید که در دور من و رفقایم تابید."},{"v":14,"t":"و چون همه بر زمین افتادیم، هاتفی راشنیدم که مرا به زبان عبرانی مخاطب ساخته، گفت: “ای شاول، شاول، چرا بر من جفا می‌کنی؟ تو را بر میخها لگد زدن دشوار است.”"},{"v":15,"t":"من گفتم: “خداوندا تو کیستی؟” گفت: “من عیسی هستم که تو بر من جفا می‌کنی."},{"v":16,"t":"و لیکن برخاسته، بر پابایست زیرا که بر تو ظاهر شدم تا تو را خادم وشاهد مقرر گردانم بر آن چیزهایی که مرا در آنهادیده‌ای و بر آنچه به تو در آن ظاهر خواهم شد."},{"v":17,"t":"و تو را رهایی خواهم داد از قوم و از امت هایی که تو را به نزد آنها خواهم فرستاد،"},{"v":18,"t":"تا چشمان ایشان را باز کنی تا از ظلمت به سوی نور و ازقدرت شیطان به‌جانب خدا برگردند تا آمرزش گناهان و میراثی در میان مقدسین بوسیله ایمانی که بر من است بیابند.”"},{"v":19,"t":"آن وقت‌ای اغریپاس پادشاه، رویای آسمانی را نافرمانی نورزیدم."},{"v":20,"t":"بلکه نخست آنانی را که در دمشق بودند و در اورشلیم و درتمامی مرز و بوم یهودیه و امت‌ها را نیز اعلام می‌نمودم که توبه کنند و به سوی خدا بازگشت نمایند و اعمال لایقه توبه را به‌جا آورند."},{"v":21,"t":"به‌سبب همین امور یهود مرا در هیکل گرفته، قصد قتل من کردند."},{"v":22,"t":"اما از خدا اعانت یافته، تا امروزباقی ماندم و خرد و بزرگ را اعلام می‌نمایم وحرفی نمی گویم، جز آنچه انبیا و موسی گفتند که می‌بایست واقع شود،"},{"v":23,"t":"که مسیح می‌بایست زحمت بیند و نوبر قیامت مردگان گشته، قوم وامت‌ها را به نور اعلام نماید.»"},{"v":24,"t":"چون او بدین سخنان، حجت خود رامی آورد، فستوس به آواز بلند گفت: «ای پولس دیوانه هستی! کثرت علم تو را دیوانه کرده است!»"},{"v":25,"t":"گفت: «ای فستوس گرامی، دیوانه نیستم بلکه سخنان راستی و هوشیاری را می‌گویم."},{"v":26,"t":"زیراپادشاهی که در حضور او به دلیری سخن می‌گویم، از این امور مطلع است، چونکه مرا یقین است که هیچ‌یک از این مقدمات بر او مخفی نیست، زیرا که این امور در خلوت واقع نشد."},{"v":27,"t":"‌ای اغریپاس پادشاه، آیا به انبیا ایمان آورده‌ای؟ می‌دانم که ایمان داری!»"},{"v":28,"t":"اغریپاس به پولس گفت: «به قلیل ترغیب می‌کنی که من مسیحی بگردم؟»"},{"v":29,"t":"پولس گفت: «از خداخواهش می‌داشتم یا به قلیل یا به کثیر، نه‌تنها توبلکه جمیع این اشخاصی که امروز سخن مرامی شنوند مثل من گردند، جز این زنجیرها!»"},{"v":30,"t":"چون این را گفت، پادشاه و والی و برنیکی وسایر مجلسیان برخاسته،"},{"v":31,"t":"رفتند و با یکدیگرگفتگو کرده، گفتند: «این شخص هیچ عملی مستوجب قتل یا حبس نکرده است.»"},{"v":32,"t":"واغریپاس به فستوس گفت: «اگر این مرد به قیصررفع دعوی خود نمی کرد، او را آزاد کردن ممکن می‌بود.»"}],"en":[{"v":1,"t":"Agrippa said to Paul, “You may speak for yourself.” Then Paul stretched out his hand, and made his defense."},{"v":2,"t":"“I think myself happy, King Agrippa, that I am to make my defense before you today concerning all the things that I am accused by the Jews,"},{"v":3,"t":"especially because you are expert in all customs and questions which are among the Jews. Therefore I beg you to hear me patiently."},{"v":4,"t":"“Indeed, all the Jews know my way of life from my youth up, which was from the beginning among my own nation and at Jerusalem;"},{"v":5,"t":"having known me from the first, if they are willing to testify, that after the strictest sect of our religion I lived a Pharisee."},{"v":6,"t":"Now I stand here to be judged for the hope of the promise made by God to our fathers,"},{"v":7,"t":"which our twelve tribes, earnestly serving night and day, hope to attain. Concerning this hope I am accused by the Jews, King Agrippa!"},{"v":8,"t":"Why is it judged incredible with you if God does raise the dead?"},{"v":9,"t":"“I myself most certainly thought that I ought to do many things contrary to the name of Jesus of Nazareth."},{"v":10,"t":"I also did this in Jerusalem. I both shut up many of the saints in prisons, having received authority from the chief priests; and when they were put to death I gave my vote against them."},{"v":11,"t":"Punishing them often in all the synagogues, I tried to make them blaspheme. Being exceedingly enraged against them, I persecuted them even to foreign cities."},{"v":12,"t":"“Whereupon as I traveled to Damascus with the authority and commission from the chief priests,"},{"v":13,"t":"at noon, O king, I saw on the way a light from the sky, brighter than the sun, shining around me and those who traveled with me."},{"v":14,"t":"When we had all fallen to the earth, I heard a voice saying to me in the Hebrew language, ‘Saul, Saul, why are you persecuting me? It is hard for you to kick against the goads.’"},{"v":15,"t":"“I said, ‘Who are you, Lord?’ “He said, ‘I am Jesus, whom you are persecuting."},{"v":16,"t":"But arise, and stand on your feet, for I have appeared to you for this purpose: to appoint you a servant and a witness both of the things which you have seen and of the things which I will reveal to you;"},{"v":17,"t":"delivering you from the people and from the Gentiles, to whom I send you,"},{"v":18,"t":"to open their eyes, that they may turn from darkness to light and from the power of Satan to God, that they may receive remission of sins and an inheritance among those who are sanctified by faith in me.’"},{"v":19,"t":"“Therefore, King Agrippa, I was not disobedient to the heavenly vision,"},{"v":20,"t":"but declared first to them of Damascus, at Jerusalem, and throughout all the country of Judea, and also to the Gentiles, that they should repent and turn to God, doing works worthy of repentance."},{"v":21,"t":"For this reason the Jews seized me in the temple and tried to kill me."},{"v":22,"t":"Having therefore obtained the help that is from God, I stand to this day testifying both to small and great, saying nothing but what the prophets and Moses said would happen,"},{"v":23,"t":"how the Christ must suffer, and how, by the resurrection of the dead, he would be first to proclaim light both to these people and to the Gentiles.”"},{"v":24,"t":"As he thus made his defense, Festus said with a loud voice, “Paul, you are crazy! Your great learning is driving you insane!”"},{"v":25,"t":"But he said, “I am not crazy, most excellent Festus, but boldly declare words of truth and reasonableness."},{"v":26,"t":"For the king knows of these things, to whom also I speak freely. For I am persuaded that none of these things is hidden from him, for this has not been done in a corner."},{"v":27,"t":"King Agrippa, do you believe the prophets? I know that you believe.”"},{"v":28,"t":"Agrippa said to Paul, “With a little persuasion are you trying to make me a Christian?”"},{"v":29,"t":"Paul said, “I pray to God, that whether with little or with much, not only you, but also all that hear me today, might become such as I am, except for these bonds.”"},{"v":30,"t":"The king rose up with the governor and Bernice, and those who sat with them."},{"v":31,"t":"When they had withdrawn, they spoke to one another, saying, “This man does nothing worthy of death or of bonds.”"},{"v":32,"t":"Agrippa said to Festus, “This man might have been set free if he had not appealed to Caesar.”"}],"hr":[{"v":1,"t":"Nato Agripa reče Pavlu: “Dopušta ti se o sebi govoriti.” Pavao ispruži ruku i stade se braniti:"},{"v":2,"t":"“Smatram se sretnim što se u svemu za što me Židovi optužuju mogu, evo, danas braniti pred tobom, kralju Agripa,"},{"v":3,"t":"jer ti najbolje poznaješ židovske običaje i zadjevice. Zato me, molim, velikodušno poslušaj.”"},{"v":4,"t":"“Dakle, život moj od najranije mladosti proveden u narodu mojem, u Jeruzalemu, znaju svi Židovi."},{"v":5,"t":"Poznaju me odavna te mogu, ako samo hoće, svjedočiti da sam po najstrožoj sljedbi naše vjere živio kao farizej."},{"v":6,"t":"I sada stojim pred sudom zbog nade u obećanje koje Bog dade ocima našim"},{"v":7,"t":"i kojemu se dovinuti nada dvanaest plemena naših, svesrdno noću i danju služeći Bogu. Za tu me nadu, kralju, tuže Židovi."},{"v":8,"t":"Zašto nevjerojatnim smatrate da Bog mrtve uskrisuje?”"},{"v":9,"t":"“Pa i ja sam nekoć smatrao da mi se svim silama boriti protiv imena Isusa Nazarećanina."},{"v":10,"t":"To sam i činio u Jeruzalemu: mnoge sam svete, pošto od velikih svećenika dobih punomoć, u tamnice zatvorio, dao svoj glas kad su ih ubijali"},{"v":11,"t":"i po svim ih sinagogama često mučenjem prisiljavao psovati i, prekomjerno bijesan na njih, progonio sam ih čak i u tuđim gradovima.”"},{"v":12,"t":"“Radi toga pođoh u Damask s punomoći i ovlaštenjem velikih svećenika"},{"v":13,"t":"kadli u pol bijela dana na putu vidjeh, kralju, kako s neba svjetlost od sunca sjajnija obasja mene i moje suputnike."},{"v":14,"t":"Pošto popadasmo na zemlju, začuh glas što mi govoraše hebrejskim jezikom: 'Savle, Savle, zašto me progoniš? Teško ti se protiv ostana praćakati.'"},{"v":15,"t":"Ja odvratih: 'Tko si, Gospodine?' Gospodin će mi: 'Ja sam Isus koga ti progoniš!"},{"v":16,"t":"Nego ustani, na noge se jer zato ti se ukazah da te postavim za poslužitelja i svjedoka onoga što si vidio i što ću ti pokazati."},{"v":17,"t":"Izbavit ću te od naroda i od pogana kojima te šaljem"},{"v":18,"t":"da im otvoriš oči pa se obrate od tame k svjetlosti, od vlasti Sotonine k Bogu te po vjeri u mene prime oproštenje grijeha i baštinu među posvećenima.'”"},{"v":19,"t":"“Otada, kralju Agripa, ne bijah neposlušan nebeskom viđenju."},{"v":20,"t":"Nego najprije onima u Damasku pa onda i u Jeruzalemu, svoj zemlji židovskoj i poganima navješćivah da se pokaju i obrate k Bogu i čine djela dostojna obraćenja."},{"v":21,"t":"Zbog toga me Židovi uhvatiše u Hramu i pokušaše ubiti."},{"v":22,"t":"Ali s pomoću Božjom sve do dana današnjega svjedočim, evo, malu i veliku, ne govoreći ništa osim onoga što Proroci govorahu i Mojsije da se ima zbiti:"},{"v":23,"t":"da će Krist trpjeti i da će on, prvouskrsli od mrtvih, svjetlost navješćivati narodu i poganima.”"},{"v":24,"t":"Dok se on tako branio, Fest će mu u sav glas: “Mahnitaš, Pavle! Veliko ti znanje mozgom zavrnulo.”"},{"v":25,"t":"“Ne mahnitam, vrli Feste, odvrati Pavao, nego riječi istine i razbora kazujem."},{"v":26,"t":"Ta znade za to kralj komu s pouzdanjem govorim. Ništa mu od toga, uvjeren sam, nije nepoznato; jer nije se to dogodilo u kakvu zakutku."},{"v":27,"t":"Vjeruješ li, kralju Agripa, Prorocima? Znam da vjeruješ!”"},{"v":28,"t":"Agripa će Pavlu: “Zamalo pa me uvjeri te kršćaninom postah!”"},{"v":29,"t":"Pavao pak: “Dao Bog te i za malo i za mnogo, ne samo ti nego i svi koji me danas slušaju postali ovakvima kakav sam ja, osim ovih okova!”"},{"v":30,"t":"Nato usta kralj, upravitelj, Berenika i oni koji su s njima zasjedali."},{"v":31,"t":"Udaljujući se govorili su među sobom: “Ovaj čovjek ne čini ništa čime bi zaslužio smrt ili okove.”"},{"v":32,"t":"Agripa pak reče Festu: “Ovaj bi čovjek mogao biti pušten da se nije prizvao na cara.”"}]},"27":{"fa":[{"v":1,"t":"چون مقرر شد که به ایطالیا برویم، پولس و چند زندانی دیگر را به یوزباشی از سپاه اغسطس که یولیوس نام داشت، سپردند."},{"v":2,"t":"و به کشتی ادرامیتینی که عازم بنادرآسیا بود، سوار شده، کوچ کردیم و ارسترخس ازاهل مکادونیه از تسالونیکی همراه ما بود."},{"v":3,"t":"روزدیگر به صیدون فرود آمدیم و یولیوس با پولس ملاطفت نموده، او را اجازت داد که نزد دوستان خود رفته، از ایشان نوازش یابد."},{"v":4,"t":"و از آنجا روانه شده، زیر قپرس گذشتیم زیرا که باد مخالف بود."},{"v":5,"t":"و از دریای کنار قیلیقیه و پمفلیه گذشته، به میرای لیکیه رسیدیم"},{"v":6,"t":"در آنجا یوزباشی کشتی اسکندریه را یافت که به ایطالیا می‌رفت و ما را برآن سوار کرد."},{"v":7,"t":"و چند روز به آهستگی رفته، به قنیدس به مشقت رسیدیم و چون باد مخالف مامی بود، در زیر کریت نزدیک سلمونی راندیم،"},{"v":8,"t":"وبه دشواری از آنجا گذشته، به موضعی که به بنادرحسنه مسمی و قریب به شهر لسائیه است رسیدیم."},{"v":9,"t":"و چون زمان منقضی شد و در این وقت سفردریا خطرناک بود، زیرا که ایام روزه گذشته بود،"},{"v":10,"t":"پولس ایشان را نصیحت کرده، گفت: «ای مردمان، می‌بینم که در این سفر ضرر و خسران بسیار پیدا خواهد شد، نه فقط بار و کشتی را بلکه جانهای ما را نیز.»"},{"v":11,"t":"ولی یوزباشی ناخدا وصاحب کشتی را بیشتر از قول پولس اعتنا نمود."},{"v":12,"t":"و چون آن بندر نیکو نبود که زمستان را در آن بسر برند، اکثر چنان مصلحت دانستند که از آنجا نقل کنند تا اگر ممکن شود خود را به فینیکسس رسانیده، زمستان را در آنجا بسر برند که آن بندری است از کریت مواجه مغرب جنوبی ومغرب شمالی."},{"v":13,"t":"و چون نسیم جنوبی وزیدن گرفت، گمان بردند که به مقصد خویش رسیدند. پس لنگر برداشتیم و از کناره کریت گذشتیم."},{"v":14,"t":"لیکن چیزی نگذشت که بادی شدید که آن رااورکلیدون می‌نامند از بالای آن زدن گرفت."},{"v":15,"t":"درساعت کشتی ربوده شده، رو به سوی باد نتوانست نهاد. پس آن را از دست داده، بی‌اختیار رانده شدیم."},{"v":16,"t":"پس در زیر جزیره‌ای که کلودی نام داشت، دوان دوان رفتیم و به دشواری زورق را درقبض خود آوردیم."},{"v":17,"t":"و آن را برداشته و معونات را استعمال نموده، کمر کشتی را بستند و چون ترسیدند که به ریگزار سیرتس فرو روند، حبال کشتی را فرو کشیدند و همچنان رانده شدند."},{"v":18,"t":"وچون طوفان بر ما غلبه می‌نمود، روز دیگر، بارکشتی را بیرون انداختند."},{"v":19,"t":"و روز سوم به‌دستهای خود آلات کشتی را به دریا انداختیم."},{"v":20,"t":"و چون روزهای بسیار آفتاب و ستارگان راندیدند و طوفانی شدید بر ما می‌افتاد، دیگر هیچ امید نجات برای ما نماند."},{"v":21,"t":"و بعد از گرسنگی بسیار، پولس در میان ایشان ایستاده، گفت: «ای مردمان، نخست می‌بایست سخن مرا پذیرفته، از کریت نقل نکرده باشید تا این ضرر و خسران را نبینید."},{"v":22,"t":"اکنون نیزشما را نصیحت می‌کنم که خاطرجمع باشید زیراکه هیچ ضرری به‌جان یکی از شما نخواهد رسیدمگر به کشتی."},{"v":23,"t":"زیرا که دوش، فرشته آن خدایی که از آن او هستم و خدمت او را می‌کنم، به من ظاهر شده،"},{"v":24,"t":"گفت: “ای پولس ترسان مباش زیراباید تو در حضور قیصر حاضر شوی. و اینک خدا همه همسفران تو را به تو بخشیده است.”"},{"v":25,"t":"پس‌ای مردمان خوشحال باشید زیرا ایمان دارم که به همانطور که به من گفت، واقع خواهدشد."},{"v":26,"t":"لیکن باید در جزیره‌ای بیفتیم.»"},{"v":27,"t":"و چون شب چهاردهم شد و هنوز دردریای ادریا به هر سو رانده می‌شدیم، در نصف شب ملاحان گمان بردند که خشکی نزدیک است."},{"v":28,"t":"پس پیمایش کرده، بیست قامت یافتند. وقدری پیشتر رفته، باز پیمایش کرده، پانزده قامت یافتند."},{"v":29,"t":"و چون ترسیدند که به صخره‌ها بیفتیم، از پشت کشتی چهار لنگر انداخته، تمنا می‌کردندکه روز شود."},{"v":30,"t":"اما چون ملاحان قصد داشتند که از کشتی فرار کنند و زورق را به دریا انداختند به بهانه‌ای که لنگرها را از پیش کشتی بکشند،"},{"v":31,"t":"پولس یوزباشی و سپاهیان را گفت: «اگر اینهادر کشتی نمانند، نجات شما ممکن نباشد.»"},{"v":32,"t":"آنگاه سپاهیان ریسمانهای زورق را بریده، گذاشتند که بیفتد."},{"v":33,"t":"چون روز نزدیک شد، پولس از همه خواهش نمود که چیزی بخورند. پس گفت: «امروز روز چهاردهم است که انتظار کشیده وچیزی نخورده، گرسنه مانده‌اید."},{"v":34,"t":"پس استدعای من این است که غذا بخورید که عافیت برای شما خواهد بود، زیرا که مویی از سر هیچ‌یک از شما نخواهد افتاد.»"},{"v":35,"t":"این بگفت و درحضور همه نان گرفته، خدا را شکر گفت و پاره کرده، خوردن گرفت."},{"v":36,"t":"پس همه قوی‌دل گشته نیز غذا خوردند."},{"v":37,"t":"و جمله نفوس در کشتی دویست و هفتاد و شش بودیم."},{"v":38,"t":"چون از غذاسیر شدند، گندم را به دریا ریخته، کشتی را سبک کردند."},{"v":39,"t":"اما چون روز، روشن شد، زمین را نشناختند؛ لیکن خلیجی دیدند که شاطی‌ای داشت. پس رای زدند که اگر ممکن شود، کشتی را بر آن برانند."},{"v":40,"t":"و بند لنگرها را بریده، آنها را دردریا گذاشتند و بندهای سکان را باز کرده، وبادبان را برای باد گشاده، راه ساحل را پیش گرفتند."},{"v":41,"t":"اما کشتی را درمجمع بحرین به پایاب رانده، مقدم آن فرو شده، بی‌حرکت ماند ولی موخرش از لطمه امواج درهم شکست."},{"v":42,"t":"آنگاه سپاهیان قصد قتل زندانیان کردند که مبادا کسی شنا کرده، بگریزد."},{"v":43,"t":"لیکن یوزباشی چون خواست پولس را برهاند، ایشان را از این اراده بازداشت و فرمود تا هر‌که شناوری داند، نخست خویشتن را به دریا انداخته به ساحل رساند."},{"v":44,"t":"وبعضی بر تختها و بعضی بر چیزهای کشتی وهمچنین همه به سلامتی به خشکی رسیدند."}],"en":[{"v":1,"t":"When it was determined that we should sail for Italy, they delivered Paul and certain other prisoners to a centurion named Julius, of the Augustan band."},{"v":2,"t":"Embarking in a ship of Adramyttium, which was about to sail to places on the coast of Asia, we put to sea, Aristarchus, a Macedonian of Thessalonica being with us."},{"v":3,"t":"The next day, we touched at Sidon. Julius treated Paul kindly and gave him permission to go to his friends and refresh himself."},{"v":4,"t":"Putting to sea from there, we sailed under the lee of Cyprus, because the winds were contrary."},{"v":5,"t":"When we had sailed across the sea which is off Cilicia and Pamphylia, we came to Myra, a city of Lycia."},{"v":6,"t":"There the centurion found a ship of Alexandria sailing for Italy, and he put us on board."},{"v":7,"t":"When we had sailed slowly many days, and had come with difficulty opposite Cnidus, the wind not allowing us further, we sailed under the lee of Crete, opposite Salmone."},{"v":8,"t":"With difficulty sailing along it we came to a certain place called Fair Havens, near the city of Lasea."},{"v":9,"t":"When much time had passed and the voyage was now dangerous because the Fast had now already gone by, Paul admonished them"},{"v":10,"t":"and said to them, “Sirs, I perceive that the voyage will be with injury and much loss, not only of the cargo and the ship, but also of our lives.”"},{"v":11,"t":"But the centurion gave more heed to the master and to the owner of the ship than to those things which were spoken by Paul."},{"v":12,"t":"Because the haven was not suitable to winter in, the majority advised going to sea from there, if by any means they could reach Phoenix and winter there, which is a port of Crete, looking southwest and northwest."},{"v":13,"t":"When the south wind blew softly, supposing that they had obtained their purpose, they weighed anchor and sailed along Crete, close to shore."},{"v":14,"t":"But before long, a stormy wind beat down from shore, which is called Euroclydon."},{"v":15,"t":"When the ship was caught and couldn’t face the wind, we gave way to it and were driven along."},{"v":16,"t":"Running under the lee of a small island called Clauda, we were able, with difficulty, to secure the boat."},{"v":17,"t":"After they had hoisted it up, they used cables to help reinforce the ship. Fearing that they would run aground on the Syrtis sand bars, they lowered the sea anchor, and so were driven along."},{"v":18,"t":"As we labored exceedingly with the storm, the next day they began to throw things overboard."},{"v":19,"t":"On the third day, they threw out the ship’s tackle with their own hands."},{"v":20,"t":"When neither sun nor stars shone on us for many days, and no small storm pressed on us, all hope that we would be saved was now taken away."},{"v":21,"t":"When they had been long without food, Paul stood up in the middle of them and said, “Sirs, you should have listened to me, and not have set sail from Crete and have gotten this injury and loss."},{"v":22,"t":"Now I exhort you to cheer up, for there will be no loss of life among you, but only of the ship."},{"v":23,"t":"For there stood by me this night an angel, belonging to the God whose I am and whom I serve,"},{"v":24,"t":"saying, ‘Don’t be afraid, Paul. You must stand before Caesar. Behold, God has granted you all those who sail with you.’"},{"v":25,"t":"Therefore, sirs, cheer up! For I believe God, that it will be just as it has been spoken to me."},{"v":26,"t":"But we must run aground on a certain island.”"},{"v":27,"t":"But when the fourteenth night had come, as we were driven back and forth in the Adriatic Sea, about midnight the sailors surmised that they were drawing near to some land."},{"v":28,"t":"They took soundings and found twenty fathoms. After a little while, they took soundings again, and found fifteen fathoms."},{"v":29,"t":"Fearing that we would run aground on rocky ground, they let go four anchors from the stern, and wished for daylight."},{"v":30,"t":"As the sailors were trying to flee out of the ship and had lowered the boat into the sea, pretending that they would lay out anchors from the bow,"},{"v":31,"t":"Paul said to the centurion and to the soldiers, “Unless these stay in the ship, you can’t be saved.”"},{"v":32,"t":"Then the soldiers cut away the ropes of the boat and let it fall off."},{"v":33,"t":"While the day was coming on, Paul begged them all to take some food, saying, “Today is the fourteenth day that you wait and continue fasting, having taken nothing."},{"v":34,"t":"Therefore I beg you to take some food, for this is for your safety; for not a hair will perish from any of your heads.”"},{"v":35,"t":"When he had said this and had taken bread, he gave thanks to God in the presence of all; then he broke it and began to eat."},{"v":36,"t":"Then they all cheered up, and they also took food."},{"v":37,"t":"In all, we were two hundred seventy-six souls on the ship."},{"v":38,"t":"When they had eaten enough, they lightened the ship, throwing out the wheat into the sea."},{"v":39,"t":"When it was day, they didn’t recognize the land, but they noticed a certain bay with a beach, and they decided to try to drive the ship onto it."},{"v":40,"t":"Casting off the anchors, they left them in the sea, at the same time untying the rudder ropes. Hoisting up the foresail to the wind, they made for the beach."},{"v":41,"t":"But coming to a place where two seas met, they ran the vessel aground. The bow struck and remained immovable, but the stern began to break up by the violence of the waves."},{"v":42,"t":"The soldiers’ counsel was to kill the prisoners, so that none of them would swim out and escape."},{"v":43,"t":"But the centurion, desiring to save Paul, stopped them from their purpose, and commanded that those who could swim should throw themselves overboard first to go toward the land;"},{"v":44,"t":"and the rest should follow, some on planks and some on other things from the ship. So they all escaped safely to the land."}],"hr":[{"v":1,"t":"Kad je odlučeno da odjedrimo u Italiju, predadoše i Pavla i neke druge uznike satniku carske čete, imenom Juliju."},{"v":2,"t":"Popesmo se na neku adramitsku lađu koja je imala ploviti u azijska mjesta pa otplovismo. S nama je bio Aristarh Makedonac, Solunjanin."},{"v":3,"t":"Sutradan doplovismo u Sidon. Julije, koji je s Pavlom čovječno postupao, dopusti mu poći k prijateljima da se pobrinu za nj."},{"v":4,"t":"Odande smo otplovili, jedrili uz Cipar - jer su nam vjetrovi bili protivni -"},{"v":5,"t":"pa preplovili more duž Cilicije i Pamfilije i stigli u Miru licijsku."},{"v":6,"t":"Ondje satnik nađe neku aleksandrijsku lađu za Italiju i ukrca nas na nju."},{"v":7,"t":"Više smo dana plovili sporo i jedva doprli do Knida. Kako nam vjetar ne dade pristati, doplovismo pod Kretu kod Salmone"},{"v":8,"t":"pa jedva jedvice ploveći uza nju, stigosmo na neko mjesto zvano Dobra pristaništa, blizu kojega je grad Laseja."},{"v":9,"t":"Kad je nakon duljeg vremena plovidba već postala pogibeljna jer je Post već bio izminuo, opominjaše Pavao:"},{"v":10,"t":"“Ljudi, govorio im je, vidim da će plovidba biti nezgodna i na veliku štetu ne samo za tovar i lađu nego i za naše živote.”"},{"v":11,"t":"Ali je satnik više vjerovao kormilaru i brodovlasniku negoli Pavlovim riječima."},{"v":12,"t":"A kako luka nije bila prikladna za zimovanje, većina je predlagala da odande otplove ne bi li kako doprli do kretske luke Feniksa, što gleda prema jugozapadu i sjeverozapadu, pa ondje prezimili."},{"v":13,"t":"Uto duhne blagi južnjak i oni, misleći da bi mogli ostvariti naum, digoše sidro i zaploviše tik uz Kretu."},{"v":14,"t":"Ali nedugo zatim razbjesni se žestok vjetar zvan sjeveroistočnjak."},{"v":15,"t":"Zahvati lađu te mu nije mogla odoljeti pa se prepustismo da nas nosi."},{"v":16,"t":"Prolazeći ispod nekog otočića zvanog Kauda, jedva uspjesmo dohvatiti čamac."},{"v":17,"t":"Podigoše ga pa upotrijebiše snast da potpašu lađu. Bojeći se pak da se ne nasuču u Sirti, spustiše prvenjaču. Tako ih je nosilo."},{"v":18,"t":"Budući da nas je oluja silovito udarala, sutradan se riješiše tovara,"},{"v":19,"t":"a treći dan svojim rukama izbaciše brodsku opremu."},{"v":20,"t":"Kako se pak više dana nije pomaljalo ni sunce ni zvijezde, a oluja bjesnjela nemalena, bila je već propala svaka nada da ćemo se spasiti."},{"v":21,"t":"Ni jelo se već dugo nije. Onda usta Pavao posred njih i reče: “Trebalo je, ljudi, poslušati me, ne se otiskivati od Krete i izbjeći ovu nepogodu i štetu."},{"v":22,"t":"Sada vas pak opominjem: razvedrite se jer ni živa duša između vas neće stradati, nego samo lađa."},{"v":23,"t":"Noćas mi se ukaza anđeo Boga čiji sam i komu služim"},{"v":24,"t":"te reče: 'Ne boj se, Pavle! Pred cara ti je stati i evo Bog ti daruje sve koji plove s tobom.'"},{"v":25,"t":"Zato razvedrite se, ljudi! Vjerujem Bogu: bit će kako mi je rečeno."},{"v":26,"t":"Ali treba da se nasučemo na neki otok.”"},{"v":27,"t":"Bijaše već četrnaesta noć što smo bili tamo-amo gonjani po Jadranu kad oko ponoći naslutiše mornari da im se primiče neka zemlja."},{"v":28,"t":"Bacivši olovnicu, nađoše dvadeset hvati dubine; malo poslije baciše je opet i nađoše ih petnaest."},{"v":29,"t":"Kako se bojahu da ne naletimo na grebene, baciše s krme četiri sidra iščekujući da se razdani."},{"v":30,"t":"Kad su mornari bili naumili uteći iz lađe i počeli spuštati čamac u more pod izlikom da s pramca kane spustiti sidra,"},{"v":31,"t":"reče Pavao satniku i vojnicima: “Ako ovi ne ostanu na lađi, vi se spasiti ne možete!”"},{"v":32,"t":"Nato vojnici presjekoše užad čamca i pustiše da padne."},{"v":33,"t":"Do pred svanuće nutkao je Pavao sve da uzmu hrane: “Četrnaesti je danas dan, reče, što bez jela čekate, ništa ne okusivši."},{"v":34,"t":"Stoga vas molim: založite nešto jer to je za vaš spas. Ta nikome od vas ni vlas s glave neće propasti.”"},{"v":35,"t":"Rekavši to, uze kruh, pred svima zahvali Bogu, razlomi i stade jesti."},{"v":36,"t":"Svi se razvedre te i oni uzmu hrane."},{"v":37,"t":"A svih nas je u lađi bilo dvjesta sedamdeset i šest duša."},{"v":38,"t":"Jednom nasićeni, stanu rasterećivati lađu bacajući žito u more."},{"v":39,"t":"Kad osvanu, mornari ne prepoznaše zemlje; razabraše neki zaljev ravne obale pa odluče, bude li moguće, u nj zavesti lađu."},{"v":40,"t":"Odriješe sidra i ostave ih u moru. Istodobno popuste i spone kormila, razapnu prvenjaču prema vjetru pa udare k obali."},{"v":41,"t":"Ali naletješe na plićak i nasukaše brod: pramac, nasađen, osta nepomičan, a krmu razdiraše žestina valova."},{"v":42,"t":"Tada vojnici naumiše poubijati sužnje da ne bi koji isplivao i pobjegao,"},{"v":43,"t":"ali im satnik, hoteći spasiti Pavla, omete naum: zapovjedi da oni koji znaju plivati najprvi poskaču i izađu na kraj,"},{"v":44,"t":"a ostali će, tko na daskama, tko na olupinama lađe. Tako svi živi i zdravi prispješe na kopno."}]},"28":{"fa":[{"v":1,"t":"و چون رستگار شدند، یافتند که جزیره ملیطه نام دارد."},{"v":2,"t":"و آن مردمان بربری باما کمال ملاطفت نمودند، زیرا به‌سبب باران که می‌بارید و سرما آتش افروخته، همه ما راپذیرفتند."},{"v":3,"t":"چون پولس مقداری هیزم فراهم کرده، بر آتش می‌نهاد، به‌سبب حرارت، افعی‌ای بیرون آمده، بر دستش چسپید."},{"v":4,"t":"چون بربریان جانور را از دستش آویخته دیدند، با یکدیگرمی گفتند: «بلاشک این شخص، خونی است که بااینکه از دریا رست، عدل نمی گذارد که زیست کند.»"},{"v":5,"t":"اما آن جانور را در آتش افکنده، هیچ ضرر نیافت."},{"v":6,"t":"پس منتظر بودند که او آماس کند یابغته افتاده، بمیرد. ولی چون انتظار بسیار کشیدندو دیدند که هیچ ضرری بدو نرسید، برگشته گفتندکه خدایی است."},{"v":7,"t":"و در آن نواحی، املاک رئیس جزیره که پوبلیوس نام داشت بود که او ما را به خانه خودطلبیده، سه روز به مهربانی مهمانی نمود."},{"v":8,"t":"ازقضا پدر پوبلیوس را رنج تب و اسهال عارض شده، خفته بود. پس پولس نزد وی آمده و دعاکرده ودست بر او گذارده، او را شفا داد."},{"v":9,"t":"و چون این امر واقع شد، سایر مریضانی که در جزیره بودند آمده، شفا یافتند."},{"v":10,"t":"و ایشان ما را اکرام بسیار نمودند و چون روانه می‌شدیم، آنچه لازم بود برای ما حاضر ساختند."},{"v":11,"t":"و بعد از سه ماه به کشتی اسکندریه که علامت جوزا داشت و زمستان را در جزیره بسربرده بود، سوار شدیم."},{"v":12,"t":"و به‌سراکوس فرودآمده، سه روز توقف نمودیم."},{"v":13,"t":"و از آنجا دورزده، به ریغیون رسیدیم و بعد از یک روز بادجنوبی وزیده، روز دوم وارد پوطیولی شدیم."},{"v":14,"t":"و در آنجا برادران یافته، حسب خواهش ایشان هفت روز ماندیم و همچنین به روم آمدیم."},{"v":15,"t":"وبرادران آنجا چون از احوال ما مطلع شدند، به استقبال ما بیرون آمدند تا فورن اپیوس و سه دکان. و پولس چون ایشان را دید، خدا را شکر نموده، قوی‌دل گشت."},{"v":16,"t":"و چون به روم رسیدیم، یوزباشی زندانیان را به‌سردار افواج خاصه سپرد. اما پولس را اجازت دادند که با یک سپاهی که محافظت او می‌کرد، در منزل خودبماند."},{"v":17,"t":"و بعد از سه روز، پولس بزرگان یهود راطلبید و چون جمع شدند به ایشان گفت: «ای برادران عزیز، با وجودی که من هیچ عملی خلاف قوم و رسوم اجداد نکرده بودم، همانا مرا در اورشلیم بسته، به‌دستهای رومیان سپردند."},{"v":18,"t":"ایشان بعد از تفحص چون در من هیچ علت قتل نیافتند، اراده کردند که مرا رها کنند."},{"v":19,"t":"ولی چون یهود مخالفت نمودند، ناچار شده به قیصررفع دعوی کردم، نه تا آنکه از امت خود شکایت کنم."},{"v":20,"t":"اکنون بدین جهت خواستم شما راملاقات کنم و سخن گویم زیرا که بجهت امیداسرائیل، بدین زنجیر بسته شدم.»"},{"v":21,"t":"وی راگفتند: «ما هیچ نوشته در حق تو از یهودیه نیافته‌ایم و نه کسی از برادرانی که از آنجا آمدند، خبری یا سخن بدی درباره تو گفته است."},{"v":22,"t":"لیکن مصلحت دانستیم از تو مقصود تو را بشنویم زیراما را معلوم است که این فرقه را در هر جا بدمی گویند.»"},{"v":23,"t":"پس چون روزی برای وی معین کردند، بسیاری نزد او به منزلش آمدند که برای ایشان به ملکوت خدا شهادت داده، شرح می‌نمود و ازتورات موسی و انبیا از صبح تا شام درباره عیسی اقامه حجت می‌کرد."},{"v":24,"t":"پس بعضی به سخنان اوایمان آوردند و بعضی ایمان نیاوردند."},{"v":25,"t":"و چون با یکدیگر معارضه می‌کردند، از او جدا شدند بعداز آنکه پولس این یک سخن را گفته بود که «روح‌القدس به وساطت اشعیای نبی به اجداد مانیکو خطاب کرده،"},{"v":26,"t":"گفته است که “نزد این قوم رفته بدیشان بگو به گوش خواهید شنید ونخواهید فهمید و نظر کرده خواهید نگریست ونخواهید دید؛"},{"v":27,"t":"زیرا دل این قوم غلیظ شده و به گوشهای سنگین می‌شنوند و چشمان خود را برهم نهاده‌اند، مبادا به چشمان ببینند و به گوشهابشنوند و به دل بفهمند و بازگشت کنند تا ایشان راشفا بخشم.”"},{"v":28,"t":"پس بر شما معلوم باد که نجات خدا نزد امت‌ها فرستاده می‌شود و ایشان خواهندشنید.»"},{"v":29,"t":"چون این را گفت یهودیان رفتند و بایکدیگر مباحثه بسیار می‌کردند."},{"v":30,"t":"اما پولس دوسال تمام در خانه اجاره‌ای خود ساکن بود و هرکه به نزد وی می‌آمد، می‌پذیرفت."},{"v":31,"t":"و به ملکوت خدا موعظه می‌نمود و با کمال دلیری درامور عیسی مسیح خداوند بدون ممانعت تعلیم می‌داد."}],"en":[{"v":1,"t":"When we had escaped, then they learned that the island was called Malta."},{"v":2,"t":"The natives showed us uncommon kindness; for they kindled a fire and received us all, because of the present rain and because of the cold."},{"v":3,"t":"But when Paul had gathered a bundle of sticks and laid them on the fire, a viper came out because of the heat and fastened on his hand."},{"v":4,"t":"When the natives saw the creature hanging from his hand, they said to one another, “No doubt this man is a murderer, whom, though he has escaped from the sea, yet Justice has not allowed to live.”"},{"v":5,"t":"However he shook off the creature into the fire, and wasn’t harmed."},{"v":6,"t":"But they expected that he would have swollen or fallen down dead suddenly, but when they watched for a long time and saw nothing bad happen to him, they changed their minds and said that he was a god."},{"v":7,"t":"Now in the neighborhood of that place were lands belonging to the chief man of the island, named Publius, who received us and courteously entertained us for three days."},{"v":8,"t":"The father of Publius lay sick of fever and dysentery. Paul entered in to him, prayed, and laying his hands on him, healed him."},{"v":9,"t":"Then when this was done, the rest also who had diseases in the island came and were cured."},{"v":10,"t":"They also honored us with many honors; and when we sailed, they put on board the things that we needed."},{"v":11,"t":"After three months, we set sail in a ship of Alexandria which had wintered in the island, whose figurehead was “The Twin Brothers.”"},{"v":12,"t":"Touching at Syracuse, we stayed there three days."},{"v":13,"t":"From there we circled around and arrived at Rhegium. After one day, a south wind sprang up, and on the second day we came to Puteoli,"},{"v":14,"t":"where we found brothers, and were entreated to stay with them for seven days. So we came to Rome."},{"v":15,"t":"From there the brothers, when they heard of us, came to meet us as far as The Market of Appius and The Three Taverns. When Paul saw them, he thanked God and took courage."},{"v":16,"t":"When we entered into Rome, the centurion delivered the prisoners to the captain of the guard, but Paul was allowed to stay by himself with the soldier who guarded him."},{"v":17,"t":"After three days Paul called together those who were the leaders of the Jews. When they had come together, he said to them, “I, brothers, though I had done nothing against the people or the customs of our fathers, still was delivered prisoner from Jerusalem into the hands of the Romans,"},{"v":18,"t":"who, when they had examined me, desired to set me free, because there was no cause of death in me."},{"v":19,"t":"But when the Jews spoke against it, I was constrained to appeal to Caesar, not that I had anything about which to accuse my nation."},{"v":20,"t":"For this cause therefore I asked to see you and to speak with you. For because of the hope of Israel I am bound with this chain.”"},{"v":21,"t":"They said to him, “We neither received letters from Judea concerning you, nor did any of the brothers come here and report or speak any evil of you."},{"v":22,"t":"But we desire to hear from you what you think. For, as concerning this sect, it is known to us that everywhere it is spoken against.”"},{"v":23,"t":"When they had appointed him a day, many people came to him at his lodging. He explained to them, testifying about God’s Kingdom, and persuading them concerning Jesus, both from the law of Moses and from the prophets, from morning until evening."},{"v":24,"t":"Some believed the things which were spoken, and some disbelieved."},{"v":25,"t":"When they didn’t agree among themselves, they departed after Paul had spoken one message: “The Holy Spirit spoke rightly through Isaiah the prophet to our fathers,"},{"v":26,"t":"saying, ‘Go to this people and say, in hearing, you will hear, but will in no way understand. In seeing, you will see, but will in no way perceive."},{"v":27,"t":"For this people’s heart has grown callous. Their ears are dull of hearing. Their eyes they have closed. Lest they should see with their eyes, hear with their ears, understand with their heart, and would turn again, then I would heal them.’"},{"v":28,"t":"“Be it known therefore to you that the salvation of God is sent to the nations, and they will listen.”"},{"v":29,"t":"When he had said these words, the Jews departed, having a great dispute among themselves."},{"v":30,"t":"Paul stayed two whole years in his own rented house and received all who were coming to him,"},{"v":31,"t":"preaching God’s Kingdom and teaching the things concerning the Lord Jesus Christ with all boldness, without hindrance."}],"hr":[{"v":1,"t":"Jednom spašeni, doznasmo da se otok zove Malta."},{"v":2,"t":"Urođenici nam iskazivahu nesvakidašnje čovjekoljublje. Zapališe krijes i okupiše nas oko njega jer je počela kiša i bilo zima."},{"v":3,"t":"Pavao nakupi naramak granja i baci na krijes kadli zbog vrućine izađe zmija i pripije mu se za ruku."},{"v":4,"t":"Kad su urođenici vidjeli gdje mu životinja visi o ruci, govorili su među sobom: “Ovaj je čovjek zacijelo ubojica: umakao je moru i Pravda mu ne da živjeti.”"},{"v":5,"t":"Ali on otrese životinju u vatru i ne bi mu ništa;"},{"v":6,"t":"a oni očekivahu da će oteći i umah se srušiti mrtav. Pošto su dugo čekali i vidjeli da mu se ništa neobično nije dogodilo, promijeniše mišljenje te stadoše govoriti da je bog."},{"v":7,"t":"U okolici onoga mjesta bilo je imanje prvaka otoka, imenom Publija. On nas je primio i tri dana uljudno gostio."},{"v":8,"t":"A Publijeva je oca uhvatila ognjica i srdobolja pa je ležao. Pavao uđe k njemu, pomoli se, stavi na nj ruke i izliječi ga."},{"v":9,"t":"Nakon toga su dolazili i drugi koji na otoku bijahu bolesni te ozdravljali."},{"v":10,"t":"Oni nas mnogim počastima počastiše i na odlasku nam priskrbiše što je potrebno."},{"v":11,"t":"Nakon tri mjeseca otplovismo aleksandrijskom lađom koja je prezimila na otoku i imala za znak Dioskure."},{"v":12,"t":"Doplovismo u Sirakuzu i ostadosmo ondje tri dana."},{"v":13,"t":"Odande ploveći uz obalu, stigosmo u Regij. Sutradan okrenu južnjak te za dva dana stigosmo u Puteole."},{"v":14,"t":"Ondje nađosmo braću koja nas zamoliše da ostanemo u njih sedam dana. Tako stigosmo u Rim."},{"v":15,"t":"Kada su tamošnja braća čula za nas, iziđoše nam u susret do Apijeva trga i Triju gostionica. Kad ih Pavao ugleda, zahvali Bogu i ohrabri se."},{"v":16,"t":"A kad uđosmo u Rim, Pavlu su dopustili stanovati zasebno, zajedno s vojnikom koji ga je čuvao."},{"v":17,"t":"Nakon tri dana sazva on židovske prvake. Kad se sabraše, reče im: “Ja, braćo, ne učinih ništa protiv naroda ni običaja otačkih, a ipak me okovana u Jeruzalemu predadoše u ruke Rimljana."},{"v":18,"t":"Oni me nakon istrage htjedoše pustiti jer nije na meni bilo ništa čime bih bio zaslužio smrt."},{"v":19,"t":"Kako se Židovi tome opriješe, bio sam prisiljen prizvati se na cara; ne dakle stoga što bih imao bilo za što tužiti svoj narod."},{"v":20,"t":"S toga dakle razloga zamolih vidjeti vas i obratiti vam se jer zbog nade Izraelove nosim ove verige.”"},{"v":21,"t":"Oni mu odvrate: “Mi o tebi nismo primili nikakva pisma iz Judeje niti nam je tko od pristigle braće o tebi što zlo javio ili rekao."},{"v":22,"t":"Nego htjeli bismo od tebe čuti što misliš jer o toj sljedbi znamo samo da joj se posvuda proturječi.”"},{"v":23,"t":"Nato urekoše dan pa dođoše mnogi k njemu u stan. Izlagao im je i svjedočio o kraljevstvu Božjemu te ih od jutra do večeri iz Mojsijeva Zakona i Proroka uvjeravao o Isusu."},{"v":24,"t":"I jedne uvjeriše njegove riječi, a drugi nisu vjerovali."},{"v":25,"t":"Nesložni tako među sobom, stadoše se razilaziti kadli im Pavao reče još jednu riječ: “Lijepo Duh Sveti po Izaiji proroku reče ocima vašim:"},{"v":26,"t":"Idi k tomu narodu i reci mu: Slušat ćete, slušati - i nećete razumjeti; gledat ćete, gledati - i nećete vidjeti!"},{"v":27,"t":"Jer usalilo se srce naroda ovoga: uši začepiše, oči zatvoriše da očima ne vide, ušima ne čuju, srcem ne razumiju te se ne obrate pa ih izliječim."},{"v":28,"t":"Neka vam je dakle svima znano: poganima je poslano ovo spasenje Božje; oni će poslušati!”"},{"v":29,"t":"#"},{"v":30,"t":"Pavao osta pune dvije godine u svom unajmljenom stanu gdje je primao sve koji su dolazili k njemu,"},{"v":31,"t":"propovijedao kraljevstvo Božje i naučavao o Gospodinu Isusu Kristu sa svom slobodom, nesmetano."}]}},"ROM":{"1":{"fa":[{"v":1,"t":"پولس، غلام عیسی مسیح و رسول خوانده شده و جدا نموده شده برای انجیل خدا،"},{"v":2,"t":"که سابق وعده آن را داده بود به وساطت انبیای خود در کتب مقدسه،"},{"v":3,"t":"درباره پسر خود که بحسب جسم از نسل داود متولد شد،"},{"v":4,"t":"و بحسب روح قدوسیت پسر خدا به قوت معروف گردید ازقیامت مردگان یعنی خداوند ما عیسی مسیح،"},{"v":5,"t":"که به او فیض و رسالت را یافتیم برای اطاعت ایمان در جمیع امت‌ها به‌خاطر اسم او،"},{"v":6,"t":"که درمیان ایشان شما نیز خوانده شده عیسی مسیح هستید"},{"v":7,"t":"به همه که در روم محبوب خدا و خوانده شده و مقدسید، فیض و سلامتی از جانب پدر ما خدا و عیسی مسیح خداوند بر شما باد."},{"v":8,"t":"اول شکر می‌کنم خدای خود را به وساطت عیسی مسیح درباره همگی شما که ایمان شما درتمام عالم شهرت یافته است؛"},{"v":9,"t":"زیرا خدایی که اورا به روح خود در انجیل پسرش خدمت می‌کنم، مرا شاهد است که چگونه پیوسته شما را یادمی کنم،"},{"v":10,"t":"و دائم در دعاهای خود مسالت می‌کنم که شاید الان آخر به اراده خدا سعادت یافته، نزد شما بیایم."},{"v":11,"t":"زیرا بسیار اشتیاق دارم که شما را ببینم تا نعمتی روحانی به شما برسانم که شما استوار بگردید،"},{"v":12,"t":"یعنی تا در میان شماتسلی یابیم از ایمان یکدیگر، ایمان من و ایمان شما."},{"v":13,"t":"لکن‌ای برادران، نمی خواهم که شمابی خبر باشید از اینکه مکرر اراده آمدن نزد شماکردم و تا به حال ممنوع شدم تا ثمری حاصل کنم در میان شما نیز چنانکه در سایر امت‌ها."},{"v":14,"t":"زیرا که یونانیان و بربریان و حکما و جهلا راهم مدیونم."},{"v":15,"t":"پس همچنین بقدر طاقت خودمستعدم که شما را نیز که در روم هستید بشارت دهم."},{"v":16,"t":"زیرا که از انجیل مسیح عار ندارم چونکه قوت خداست، برای نجات هر کس که ایمان آورد، اول یهود و پس یونانی،"},{"v":17,"t":"که در آن عدالت خدا مکشوف می‌شود، از ایمان تا ایمان، چنانکه مکتوب است که عادل به ایمان زیست خواهد نمود."},{"v":18,"t":"زیرا غضب خدا از آسمان مکشوف می‌شود بر هر بی‌دینی و ناراستی مردمانی که راستی را در ناراستی باز می‌دارند."},{"v":19,"t":"چونکه آنچه از خدا می‌توان شناخت، در ایشان ظاهراست زیرا خدا آن را بر ایشان ظاهر کرده است."},{"v":20,"t":"زیرا که چیزهای نادیده او یعنی قوت سرمدی و الوهیتش از حین آفرینش عالم بوسیله کارهای او فهمیده و دیده می‌شود تا ایشان را عذری نباشد."},{"v":21,"t":"زیرا هر‌چند خدا را شناختند، ولی اورا چون خدا تمجید و شکر نکردند بلکه درخیالات خود باطل گردیده، دل بی‌فهم ایشان تاریک گشت."},{"v":22,"t":"ادعای حکمت می‌کردند واحمق گردیدند."},{"v":23,"t":"و جلال خدای غیرفانی را به شبیه صورت انسان فانی و طیور و بهایم وحشرات تبدیل نمودند."},{"v":24,"t":"لهذا خدا نیز ایشان رادر شهوات دل خودشان به ناپاکی تسلیم فرمود تادر میان خود بدنهای خویش را خوار سازند،"},{"v":25,"t":"که ایشان حق خدا را به دروغ مبدل کردند وعبادت و خدمت نمودند مخلوق را به عوض خالقی که تا ابدالاباد متبارک است. آمین."},{"v":26,"t":"از این سبب خدا ایشان را به هوسهای خباثت تسلیم نمود، به نوعی که زنانشان نیز عمل طبیعی را به آنچه خلاف طبیعت است تبدیل نمودند."},{"v":27,"t":"و همچنین مردان هم استعمال طبیعی زنان را ترک کرده، از شهوات خود با یکدیگرسوختند. مرد با مرد مرتکب اعمال زشت شده، عقوبت سزاوار تقصیر خود را در خود یافتند."},{"v":28,"t":"و چون روا نداشتند که خدا را در دانش خودنگاه دارند، خدا ایشان را به ذهن مردود واگذاشت تا کارهای ناشایسته به‌جا آورند."},{"v":29,"t":"مملو از هرنوع ناراستی و شرارت و طمع و خباثت؛ پر ازحسد و قتل و جدال و مکر و بدخویی؛"},{"v":30,"t":"غمازان و غیبت کنندگان و دشمنان خدا و اهانت کنندگان و متکبران و لافزنان و مبدعان شر و نامطیعان والدین؛"},{"v":31,"t":"بی‌فهم و بی‌وفا و بی‌الفت و بی‌رحم."},{"v":32,"t":"زیرا هر‌چند انصاف خدا را می‌دانند که کنندگان چنین کارها مستوجب موت هستند، نه فقط آنها را می‌کنند بلکه کنندگان را نیز خوش می‌دارند."}],"en":[{"v":1,"t":"Paul, a servant of Jesus Christ, called to be an apostle, set apart for the Good News of God,"},{"v":2,"t":"which he promised before through his prophets in the holy Scriptures,"},{"v":3,"t":"concerning his Son, who was born of the offspring of David according to the flesh,"},{"v":4,"t":"who was declared to be the Son of God with power according to the Spirit of holiness, by the resurrection from the dead, Jesus Christ our Lord,"},{"v":5,"t":"through whom we received grace and apostleship for obedience of faith among all the nations for his name’s sake;"},{"v":6,"t":"among whom you are also called to belong to Jesus Christ;"},{"v":7,"t":"to all who are in Rome, beloved of God, called to be saints: Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":8,"t":"First, I thank my God through Jesus Christ for all of you, that your faith is proclaimed throughout the whole world."},{"v":9,"t":"For God is my witness, whom I serve in my spirit in the Good News of his Son, how unceasingly I make mention of you always in my prayers,"},{"v":10,"t":"requesting, if by any means now at last I may be prospered by the will of God to come to you."},{"v":11,"t":"For I long to see you, that I may impart to you some spiritual gift, to the end that you may be established;"},{"v":12,"t":"that is, that I with you may be encouraged in you, each of us by the other’s faith, both yours and mine."},{"v":13,"t":"Now I don’t desire to have you unaware, brothers, that I often planned to come to you (and was hindered so far), that I might have some fruit among you also, even as among the rest of the Gentiles."},{"v":14,"t":"I am debtor both to Greeks and to foreigners, both to the wise and to the foolish."},{"v":15,"t":"So as much as is in me, I am eager to preach the Good News to you also who are in Rome."},{"v":16,"t":"For I am not ashamed of the Good News of Christ, because it is the power of God for salvation for everyone who believes, for the Jew first, and also for the Greek."},{"v":17,"t":"For in it is revealed God’s righteousness from faith to faith. As it is written, “But the righteous shall live by faith.”"},{"v":18,"t":"For the wrath of God is revealed from heaven against all ungodliness and unrighteousness of men who suppress the truth in unrighteousness,"},{"v":19,"t":"because that which is known of God is revealed in them, for God revealed it to them."},{"v":20,"t":"For the invisible things of him since the creation of the world are clearly seen, being perceived through the things that are made, even his everlasting power and divinity, that they may be without excuse."},{"v":21,"t":"Because knowing God, they didn’t glorify him as God, and didn’t give thanks, but became vain in their reasoning, and their senseless heart was darkened."},{"v":22,"t":"Professing themselves to be wise, they became fools,"},{"v":23,"t":"and traded the glory of the incorruptible God for the likeness of an image of corruptible man, and of birds, four-footed animals, and creeping things."},{"v":24,"t":"Therefore God also gave them up in the lusts of their hearts to uncleanness, that their bodies should be dishonored among themselves;"},{"v":25,"t":"who exchanged the truth of God for a lie, and worshiped and served the creature rather than the Creator, who is blessed forever. Amen."},{"v":26,"t":"For this reason, God gave them up to vile passions. For their women changed the natural function into that which is against nature."},{"v":27,"t":"Likewise also the men, leaving the natural function of the woman, burned in their lust toward one another, men doing what is inappropriate with men, and receiving in themselves the due penalty of their error."},{"v":28,"t":"Even as they refused to have God in their knowledge, God gave them up to a reprobate mind, to do those things which are not fitting;"},{"v":29,"t":"being filled with all unrighteousness, sexual immorality, wickedness, covetousness, malice; full of envy, murder, strife, deceit, evil habits, secret slanderers,"},{"v":30,"t":"backbiters, hateful to God, insolent, arrogant, boastful, inventors of evil things, disobedient to parents,"},{"v":31,"t":"without understanding, covenant breakers, without natural affection, unforgiving, unmerciful;"},{"v":32,"t":"who, knowing the ordinance of God, that those who practice such things are worthy of death, not only do the same, but also approve of those who practice them."}],"hr":[{"v":1,"t":"Pavao, sluga Krista Isusa, pozvan za apostola, odlučen za evanđelje Božje -"},{"v":2,"t":"koje Bog unaprijed obećavaše po svojim prorocima u Pismima svetim"},{"v":3,"t":"o Sinu svome, potomku Davidovu po tijelu,"},{"v":4,"t":"postavljenu Sinom Božjim, u snazi, po Duhu posvetitelju uskrsnućem od mrtvih, o Isusu Kristu, Gospodinu našemu,"},{"v":5,"t":"po komu primismo milost i apostolstvo da na slavu imena njegova k poslušnosti vjere privodimo sve pogane"},{"v":6,"t":"među kojima ste i vi pozvanici Isusa Krista:"},{"v":7,"t":"svima u Rimu, miljenicima Božjim, pozvanicima, svetima. Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista."},{"v":8,"t":"Ponajprije zahvaljujem Bogu mojemu po Isusu Kristu za sve vas: što se vaša vjera navješćuje po svem svijetu."},{"v":9,"t":"Doista, svjedok mi je Bog - komu duhom svojim služim u evanđelju Sina njegova - da vas se"},{"v":10,"t":"u svojim molitvama neprekidno spominjem i uvijek molim ne bi li mi se već jednom s voljom Božjom nekako posrećilo doći k vama."},{"v":11,"t":"Jer čeznem vidjeti vas da vam predam nešto dara duhovnoga te se ojačate, zapravo -"},{"v":12,"t":"da se zajedno s vama ohrabrim zajedničkom vjerom, vašom i mojom."},{"v":13,"t":"A ne bih htio, braćo, da ne znate: često sam bio nakanio doći k vama - i sve dosad bio spriječen - da i među vama uberem koji plod kao i među drugim narodima."},{"v":14,"t":"Dužnik sam Grcima i barbarima, mudracima i neznalicama."},{"v":15,"t":"Odatle moja nakana da i vama u Rimu navijestim evanđelje."},{"v":16,"t":"Ne stidim se, uistinu, evanđelja: ono je snaga Božja na spasenje svakomu tko vjeruje - Židovu najprije, pa Grku."},{"v":17,"t":"Jer pravednost se Božja od vjere k vjeri u njemu otkriva kao što je pisano: Pravednik će od vjere živjeti."},{"v":18,"t":"Otkriva se doista s neba gnjev Božji na svaku bezbožnost i nepravednost ljudi koji istinu sputavaju nepravednošću."},{"v":19,"t":"Jer što se o Bogu može spoznati, očito im je: Bog im očitova."},{"v":20,"t":"Uistinu, ono nevidljivo njegovo, vječna njegova moć i božanstvo, onamo od stvaranja svijeta, umom se po djelima razabire tako da nemaju isprike."},{"v":21,"t":"Jer premda upoznaše Boga, ne iskazaše mu kao Bogu ni slavu ni zahvalnost, nego ishlapiše u mozganjima svojim te se pomrači bezumno srce njihovo."},{"v":22,"t":"Gradeći se mudrima, poludješe i"},{"v":23,"t":"zamijeniše slavu neraspadljivog Boga likom, obličjem raspadljiva čovjeka, i ptica, i četveronožaca, i gmazova."},{"v":24,"t":"Zato ih je Bog po pohotama srdaca njihovih predao nečistoći te sami obeščašćuju svoja tijela,"},{"v":25,"t":"oni što su Istinu - Boga zamijenili lažju, častili i štovali stvorenje umjesto Stvoritelja, koji je blagoslovljen u vjekove. Amen."},{"v":26,"t":"Stoga ih je Bog predao sramotnim strastima: njihove žene zamijeniše naravno općenje protunaravnim,"},{"v":27,"t":"a tako su i muškarci napustili naravno općenje sa ženom i raspalili se pohotom jedni za drugima te muškarci s muškarcima sramotno čine i sami na sebi primaju zasluženu plaću svoga zastranjenja."},{"v":28,"t":"I kako nisu smatrali vrijednim držati se spoznaje Boga, predade ih Bog nevaljanu umu te čine što ne dolikuje,"},{"v":29,"t":"puni svake nepravde, pakosti, lakomosti, zloće; puni zavisti, ubojstva, svađe, prijevare, zlonamjernosti; došaptavači,"},{"v":30,"t":"klevetnici, mrzitelji Boga, drznici, oholice, preuzetnici, izmišljači zala, roditeljima neposlušni,"},{"v":31,"t":"nerazumni, nevjerni, bešćutni, nemilosrdni."},{"v":32,"t":"Znaju za odredbu Božju - da smrt zaslužuju koji takvo što čine - a oni ne samo da to čine nego i povlađuju onima koji čine."}]},"2":{"fa":[{"v":1,"t":"لهذا‌ای آدمی که حکم می‌کنی، هر‌که باشی عذری نداری زیرا که به آنچه بردیگری حکم می‌کنی، فتوا بر خود می‌دهی، زیراتو که حکم می‌کنی، همان کارها را به عمل می‌آوری."},{"v":2,"t":"و می‌دانیم که حکم خدا بر کنندگان چنین اعمال بر‌حق است."},{"v":3,"t":"پس‌ای آدمی که برکنندگان چنین اعمال حکم می‌کنی و خود همان را می‌کنی، آیا گمان می‌بری که تو از حکم خداخواهی رست؟"},{"v":4,"t":"یا آنکه دولت مهربانی و صبر وحلم او را ناچیز می‌شماری و نمی دانی که مهربانی خدا تو را به توبه می‌کشد؟"},{"v":5,"t":"و به‌سبب قساوت و دل ناتوبه‌کار خود، غضب را ذخیره می‌کنی برای خود در روز غضب و ظهور داوری عادله خدا"},{"v":6,"t":"که به هر کس برحسب اعمالش جزاخواهد داد:"},{"v":7,"t":"اما به آنانی که با صبر در اعمال نیکوطالب جلال و اکرام و بقایند، حیات جاودانی را؛"},{"v":8,"t":"و اما به اهل تعصب که اطاعت راستی نمی کنندبلکه مطیع ناراستی می‌باشند، خشم و غضب"},{"v":9,"t":"وعذاب و ضیق بر هر نفس بشری که مرتکب بدی می‌شود، اول بر یهود و پس بر یونانی؛"},{"v":10,"t":"لکن جلال و اکرام و سلامتی بر هر نیکوکار، نخست بریهود و بر یونانی نیز."},{"v":11,"t":"زیرا نزد خدا طرفداری نیست،"},{"v":12,"t":"زیراآنانی که بدون شریعت گناه کنند، بی‌شریعت نیزهلاک شوند و آنانی که با شریعت گناه کنند، ازشریعت بر ایشان حکم خواهد شد."},{"v":13,"t":"از آن جهت که شنوندگان شریعت در حضور خدا عادل نیستند بلکه کنندگان شریعت عادل شمرده خواهند شد."},{"v":14,"t":"زیرا هرگاه امت هایی که شریعت ندارند کارهای شریعت را به طبیعت به‌جا آرند، اینان هرچند شریعت ندارند، برای خود شریعت هستند،"},{"v":15,"t":"چونکه از ایشان ظاهر می‌شود که عمل شریعت بر دل ایشان مکتوب است و ضمیرایشان نیز گواهی می‌دهد و افکار ایشان با یکدیگریا مذمت می‌کنند یا عذر می‌آورند،"},{"v":16,"t":"در روزی که خدا رازهای مردم را داوری خواهد نمود به وساطت عیسی مسیح برحسب بشارت من."},{"v":17,"t":"پس اگر تو مسمی به یهود هستی و برشریعت تکیه می‌کنی و به خدا فخر می‌نمایی،"},{"v":18,"t":"و اراده او را می‌دانی و از شریعت تربیت یافته، چیزهای افضل را می‌گزینی،"},{"v":19,"t":"و یقین داری که خود هادی کوران و نور ظلمتیان"},{"v":20,"t":"و مودب جاهلان و معلم اطفال هستی و در شریعت صورت معرفت و راستی را داری،"},{"v":21,"t":"پس‌ای کسی‌که دیگران را تعلیم می‌دهی، چرا خود رانمی آموزی؟ و وعظ می‌کنی که دزدی نباید کرد، آیا خود دزدی می‌کنی؟"},{"v":22,"t":"و از زنا کردن نهی می‌کنی، آیا خود زانی نیستی؟ و از بتها نفرت داری، آیا خود معبدها را غارت نمی کنی؟"},{"v":23,"t":"و به شریعت فخر می‌کنی، آیا به تجاوز از شریعت خدا را اهانت نمی کنی؟"},{"v":24,"t":"زیرا که به‌سبب شمادر میان امت‌ها اسم خدا را کفر می‌گویند، چنانکه مکتوب است."},{"v":25,"t":"زیرا ختنه سودمند است هرگاه به شریعت عمل نمایی. اما اگر از شریعت تجاوزنمایی، ختنه تو نامختونی گشته است."},{"v":26,"t":"پس اگرنامختونی، احکام شریعت را نگاه دارد، آیانامختونی او ختنه شمرده نمی شود؟"},{"v":27,"t":"ونامختونی طبیعی هرگاه شریعت را به‌جا آرد، حکم خواهد کرد بر تو که با وجود کتب و ختنه ازشریعت تجاوز می‌کنی."},{"v":28,"t":"زیرا آنکه در ظاهراست، یهودی نیست و آنچه در ظاهر در جسم است، ختنه نی."},{"v":29,"t":"بلکه یهود آن است که در باطن باشد و ختنه آنکه قلبی باشد، در روح نه در حرف که مدح آن نه از انسان بلکه از خداست."}],"en":[{"v":1,"t":"Therefore you are without excuse, O man, whoever you are who judge. For in that which you judge another, you condemn yourself. For you who judge practice the same things."},{"v":2,"t":"We know that the judgment of God is according to truth against those who practice such things."},{"v":3,"t":"Do you think this, O man who judges those who practice such things, and do the same, that you will escape the judgment of God?"},{"v":4,"t":"Or do you despise the riches of his goodness, forbearance, and patience, not knowing that the goodness of God leads you to repentance?"},{"v":5,"t":"But according to your hardness and unrepentant heart you are treasuring up for yourself wrath in the day of wrath, revelation, and of the righteous judgment of God,"},{"v":6,"t":"who “will pay back to everyone according to their works:”"},{"v":7,"t":"to those who by perseverance in well-doing seek for glory, honor, and incorruptibility, eternal life;"},{"v":8,"t":"but to those who are self-seeking and don’t obey the truth, but obey unrighteousness, will be wrath, indignation,"},{"v":9,"t":"oppression, and anguish on every soul of man who does evil, to the Jew first, and also to the Greek."},{"v":10,"t":"But glory, honor, and peace go to every man who does good, to the Jew first, and also to the Greek."},{"v":11,"t":"For there is no partiality with God."},{"v":12,"t":"For as many as have sinned without the law will also perish without the law. As many as have sinned under the law will be judged by the law."},{"v":13,"t":"For it isn’t the hearers of the law who are righteous before God, but the doers of the law will be justified"},{"v":14,"t":"(for when Gentiles who don’t have the law do by nature the things of the law, these, not having the law, are a law to themselves,"},{"v":15,"t":"in that they show the work of the law written in their hearts, their conscience testifying with them, and their thoughts among themselves accusing or else excusing them)"},{"v":16,"t":"in the day when God will judge the secrets of men, according to my Good News, by Jesus Christ."},{"v":17,"t":"Indeed you bear the name of a Jew, rest on the law, glory in God,"},{"v":18,"t":"know his will, and approve the things that are excellent, being instructed out of the law,"},{"v":19,"t":"and are confident that you yourself are a guide of the blind, a light to those who are in darkness,"},{"v":20,"t":"a corrector of the foolish, a teacher of babies, having in the law the form of knowledge and of the truth."},{"v":21,"t":"You therefore who teach another, don’t you teach yourself? You who preach that a man shouldn’t steal, do you steal?"},{"v":22,"t":"You who say a man shouldn’t commit adultery, do you commit adultery? You who abhor idols, do you rob temples?"},{"v":23,"t":"You who glory in the law, do you dishonor God by disobeying the law?"},{"v":24,"t":"For “the name of God is blasphemed among the Gentiles because of you,” just as it is written."},{"v":25,"t":"For circumcision indeed profits, if you are a doer of the law, but if you are a transgressor of the law, your circumcision has become uncircumcision."},{"v":26,"t":"If therefore the uncircumcised keep the ordinances of the law, won’t his uncircumcision be accounted as circumcision?"},{"v":27,"t":"Won’t those who are physically uncircumcised, but fulfill the law, judge you, who with the letter and circumcision are a transgressor of the law?"},{"v":28,"t":"For he is not a Jew who is one outwardly, neither is that circumcision which is outward in the flesh;"},{"v":29,"t":"but he is a Jew who is one inwardly, and circumcision is that of the heart, in the spirit, not in the letter; whose praise is not from men, but from God."}],"hr":[{"v":1,"t":"Zato nemaš isprike, čovječe koji sudiš, tko god ti bio. Jer time što drugoga sudiš, sebe osuđuješ: ta to isto činiš ti što sudiš."},{"v":2,"t":"Znamo pak: Bog po istini sudi one koji takvo što čine."},{"v":3,"t":"Misliš li da ćeš izbjeći sudu Božjemu, ti čovječe što sudiš one koji takvo što čine, a sam to isto činiš?"},{"v":4,"t":"Ili prezireš bogatstvo dobrote, strpljivosti i velikodušnosti njegove ne shvaćajući da te dobrota Božja k obraćenju privodi?"},{"v":5,"t":"Tvrdokornošću svojom i srcem koje neće obraćenja zgrćeš na se gnjev za Dan gnjeva i objavljenja pravedna suda Boga"},{"v":6,"t":"koji će uzvratiti svakom po djelima:"},{"v":7,"t":"onima koji postojanošću u dobrim djelima ištu slavu, čast i neraspadljivost - život vječni;"},{"v":8,"t":"buntovnicima pak i nepokornima istini, a pokornima nepravdi - gnjev i srdžba!"},{"v":9,"t":"Nevolja i tjeskoba na svaku dušu čovječju koja čini zlo, na Židova najprije, pa na Grka;"},{"v":10,"t":"a slava, čast i mir svakomu koji čini dobro, Židovu najprije, pa Grku!"},{"v":11,"t":"Ta u Boga nema pristranosti."},{"v":12,"t":"Uistinu koji bez Zakona sagriješiše, bez Zakona će i propasti; i koji pod Zakonom sagriješiše, po Zakonu će biti suđeni."},{"v":13,"t":"Ne, pred Bogom nisu pravedni slušatelji Zakona, nego - izvršitelji će Zakona biti opravdani."},{"v":14,"t":"Ta kad se god pogani, koji nemaju Zakona, po naravi drže Zakona, i nemajući Zakona, oni su sami sebi Zakon:"},{"v":15,"t":"pokazuju da je ono što Zakon nalaže upisano u srcima njihovim. O tom svjedoči i njihova savjest, a i prosuđivanja kojima se među sobom optužuju ili brane."},{"v":16,"t":"To će se očitovati na Dan u koji će, po mojem evanđelju, Bog po Isusu Kristu suditi ono što je skriveno u ljudima."},{"v":17,"t":"Ako pak ti koji se Židovom nazivaš, koji mirno počivaš na Zakonu i dičiš se Bogom,"},{"v":18,"t":"koji poznaješ Volju i iz Zakona poučen razlučuješ što je bolje"},{"v":19,"t":"te si uvjeren da si vođa slijepih, svjetlo onih u tami,"},{"v":20,"t":"odgojitelj nerazumnih, učitelj nejačadi jer u Zakonu imaš oličenje znanja i istine;"},{"v":21,"t":"ti, dakle, koji drugoga učiš, sam sebe ne učiš! Ti koji propovijedaš da se ne krade, kradeš!"},{"v":22,"t":"Ti koji zabranjuješ preljub, preljub počinjaš! Ti komu su odvratni kumiri, pljačkaš hramove!"},{"v":23,"t":"Ti koji se Zakonom dičiš, kršenjem toga Zakona Boga obeščašćuješ!"},{"v":24,"t":"Doista, kako je pisano, ime se Božje zbog vas huli među narodima."},{"v":25,"t":"Da, obrezanje koristi ako vršiš Zakon; ako pak kršiš Zakon, obrezanje tvoje postalo je neobrezanje."},{"v":26,"t":"Ako dakle neobrezani opslužuje propise Zakona, neće li se njegovo neobrezanje smatrati obrezanjem?"},{"v":27,"t":"I onaj koji je podrijetlom neobrezanik, a ispunja Zakon, sudit će tebi koji si, uza sve slovo i obrezanje, prijestupnik Zakona."},{"v":28,"t":"Ta nije Židov tko je Židov naizvana i nije obrezanje ono izvana,"},{"v":29,"t":"na tijelu, nego pravi je Židov u nutrini i pravo je obrezanje u srcu, po duhu, ne po slovu. Pohvala mu nije od ljudi, nego od Boga."}]},"3":{"fa":[{"v":1,"t":"پس برتری یهود چیست؟ و یا از ختنه چه فایده؟"},{"v":2,"t":"بسیار از هر جهت؛ اول آنکه بدیشان کلام خدا امانت داده شده است."},{"v":3,"t":"زیرا که چه بگوییم اگر بعضی ایمان نداشتند؟ آیابی ایمانی‌ایشان امانت خدا را باطل می‌سازد؟"},{"v":4,"t":"حاشا! بلکه خدا راستگو باشد و هر انسان دروغگو، چنانکه مکتوب است: «تا اینکه درسخنان خود مصدق شوی و در داوری خودغالب آیی.»"},{"v":5,"t":"لکن اگر ناراستی ما عدالت خدا را ثابت می‌کند، چه گوییم؟ آیا خدا ظالم است وقتی که غضب می‌نماید؟ بطور انسان سخن می‌گویم."},{"v":6,"t":"حاشا! در این صورت خدا چگونه عالم راداوری خواهد کرد؟"},{"v":7,"t":"زیرا اگر به دروغ من، راستی خدا برای جلال او افزون شود، پس چرا برمن نیز چون گناهکار حکم شود؟"},{"v":8,"t":"و چرا نگوییم، چنانکه بعضی بر ما افترا می‌زنند و گمان می‌برندکه ما چنین می‌گوییم، بدی بکنیم تا نیکویی حاصل شود؟ که قصاص ایشان به انصاف است."},{"v":9,"t":"پس چه گوییم؟ آیا برتری داریم؟ نه به هیچ وجه! زیرا پیش ادعا وارد آوردیم که یهود ویونانیان هر دو به گناه گرفتارند."},{"v":10,"t":"چنانکه مکتوب است که «کسی عادل نیست، یکی هم نی."},{"v":11,"t":"کسی فهیم نیست، کسی طالب خدا نیست."},{"v":12,"t":"همه گمراه و جمیع باطل گردیده‌اند. نیکوکاری نیست یکی هم نی."},{"v":13,"t":"گلوی ایشان گور گشاده است و به زبانهای خود فریب می‌دهند. زهر مار در زیر لب ایشان است،"},{"v":14,"t":"ودهان ایشان پر از لعنت و تلخی است."},{"v":15,"t":"پایهای ایشان برای خون ریختن شتابان است."},{"v":16,"t":"هلاکت و پریشانی در طریقهای ایشان است،"},{"v":17,"t":"و طریق سلامتی را ندانسته‌اند."},{"v":18,"t":"خدا ترسی درچشمانشان نیست.»"},{"v":19,"t":"الان آگاه هستیم که آنچه شریعت می‌گوید، به اهل شریعت خطاب می‌کند تا هر دهانی بسته شود و تمام عالم زیر قصاص خدا آیند."},{"v":20,"t":"ازآنجا که به اعمال شریعت هیچ بشری در حضوراو عادل شمرده نخواهد شد، چونکه از شریعت دانستن گناه است."},{"v":21,"t":"لکن الحال بدون شریعت، عدالت خداظاهر شده است، چنانکه تورات و انبیا بر آن شهادت می‌دهند؛"},{"v":22,"t":"یعنی عدالت خدا که بوسیله ایمان به عیسی مسیح است، به همه و کل آنانی که ایمان آورند. زیرا که هیچ تفاوتی نیست،"},{"v":23,"t":"زیراهمه گناه کرده‌اند واز جلال خدا قاصر می‌باشند،"},{"v":24,"t":"و به فیض او مجان عادل شمرده می‌شوند به وساطت آن فدیه‌ای که در عیسی مسیح است."},{"v":25,"t":"که خدا او را از قبل معین کرد تا کفاره باشد به واسطه ایمان به وسیله خون او تا آنکه عدالت خود را ظاهر سازد، به‌سبب فرو گذاشتن خطایای سابق در حین تحمل خدا،"},{"v":26,"t":"برای اظهار عدالت خود در زمان حاضر، تا او عادل شود و عادل شمارد هرکسی را که به عیسی ایمان آورد."},{"v":27,"t":"پس جای فخر کجا است؟ برداشته شده است! به کدام شریعت؟ آیا به شریعت اعمال؟ نی بلکه به شریعت ایمان."},{"v":28,"t":"زیرا یقین می‌دانیم که انسان بدون اعمال شریعت، محض ایمان عادل شمرده می‌شود."},{"v":29,"t":"آیا او خدای یهود است فقط؟ مگر خدای امت‌ها هم نیست؟ البته خدای امت‌ها نیز است."},{"v":30,"t":"زیرا واحد است خدایی که اهل ختنه را از ایمان، و نامختونان را به ایمان عادل خواهد شمرد."},{"v":31,"t":"پس آیا شریعت را به ایمان باطل می‌سازیم؟ حاشا! بلکه شریعت رااستوار می‌داریم."}],"en":[{"v":1,"t":"Then what advantage does the Jew have? Or what is the profit of circumcision?"},{"v":2,"t":"Much in every way! Because first of all, they were entrusted with the revelations of God."},{"v":3,"t":"For what if some were without faith? Will their lack of faith nullify the faithfulness of God?"},{"v":4,"t":"May it never be! Yes, let God be found true, but every man a liar. As it is written, “that you might be justified in your words, and might prevail when you come into judgment.”"},{"v":5,"t":"But if our unrighteousness commends the righteousness of God, what will we say? Is God unrighteous who inflicts wrath? I speak like men do."},{"v":6,"t":"May it never be! For then how will God judge the world?"},{"v":7,"t":"For if the truth of God through my lie abounded to his glory, why am I also still judged as a sinner?"},{"v":8,"t":"Why not (as we are slanderously reported, and as some affirm that we say), “Let’s do evil, that good may come?” Those who say so are justly condemned."},{"v":9,"t":"What then? Are we better than they? No, in no way. For we previously warned both Jews and Greeks that they are all under sin."},{"v":10,"t":"As it is written, “There is no one righteous; no, not one."},{"v":11,"t":"There is no one who understands. There is no one who seeks after God."},{"v":12,"t":"They have all turned away. They have together become unprofitable. There is no one who does good, no, not so much as one.”"},{"v":13,"t":"“Their throat is an open tomb. With their tongues they have used deceit.” “The poison of vipers is under their lips.”"},{"v":14,"t":"“Their mouth is full of cursing and bitterness.”"},{"v":15,"t":"“Their feet are swift to shed blood."},{"v":16,"t":"Destruction and misery are in their ways."},{"v":17,"t":"The way of peace, they haven’t known.”"},{"v":18,"t":"“There is no fear of God before their eyes.”"},{"v":19,"t":"Now we know that whatever things the law says, it speaks to those who are under the law, that every mouth may be closed, and all the world may be brought under the judgment of God."},{"v":20,"t":"Because by the works of the law, no flesh will be justified in his sight; for through the law comes the knowledge of sin."},{"v":21,"t":"But now apart from the law, a righteousness of God has been revealed, being testified by the law and the prophets;"},{"v":22,"t":"even the righteousness of God through faith in Jesus Christ to all and on all those who believe. For there is no distinction,"},{"v":23,"t":"for all have sinned, and fall short of the glory of God;"},{"v":24,"t":"being justified freely by his grace through the redemption that is in Christ Jesus,"},{"v":25,"t":"whom God sent to be an atoning sacrifice through faith in his blood, for a demonstration of his righteousness through the passing over of prior sins, in God’s forbearance;"},{"v":26,"t":"to demonstrate his righteousness at this present time, that he might himself be just and the justifier of him who has faith in Jesus."},{"v":27,"t":"Where then is the boasting? It is excluded. By what kind of law? Of works? No, but by a law of faith."},{"v":28,"t":"We maintain therefore that a man is justified by faith apart from the works of the law."},{"v":29,"t":"Or is God the God of Jews only? Isn’t he the God of Gentiles also? Yes, of Gentiles also,"},{"v":30,"t":"since indeed there is one God who will justify the circumcised by faith and the uncircumcised through faith."},{"v":31,"t":"Do we then nullify the law through faith? May it never be! No, we establish the law."}],"hr":[{"v":1,"t":"Koja je dakle prednost Židova? Ili kakva korist od obrezanja?"},{"v":2,"t":"Velika u svakom pogledu. Ponajprije: povjerena su im obećanja Božja."},{"v":3,"t":"Da, a što ako su se neki iznevjerili? Neće li njihova nevjernost obeskrijepiti vjernost Božju?"},{"v":4,"t":"Nipošto! Nego neka Bog bude istinit, a svaki čovjek lažac, kao što je pisano: Da pravedan budeš po obećanjima svojim i pobijediš kada te sudili budu."},{"v":5,"t":"Ako pak naša nepravednost ističe Božju pravednost, što ćemo na to reći? Nije li onda - po ljudsku govorim - nepravedan Bog koji daje maha gnjevu?"},{"v":6,"t":"Nipošto! Ta kako će inače Bog suditi svijet?"},{"v":7,"t":"Ako je, doista, istina Božja po mojoj lažljivosti obilno zasjala njemu na slavu, zašto da ja još budem suđen kao grešnik?"},{"v":8,"t":"I zar da ne “činimo zlo da dođe dobro”, kako nas kleveću i kako neki kažu da govorimo? Sud ih pravedni čeka!"},{"v":9,"t":"Što dakle? Imamo li prednost? Ne baš! Jer upravo optužismo sve, i Židove i Grke, da su pod grijehom,"},{"v":10,"t":"kao što je pisano: Nema pravedna ni jednoga,"},{"v":11,"t":"nema razumna, nema ga tko bi Boga tražio."},{"v":12,"t":"Svi skrenuše, svi se zajedno pokvariše, nitko da čini dobro - nijednoga nema."},{"v":13,"t":"Grob otvoren grlo je njihovo, jezikom lažno laskaju, pod usnama im je otrov ljutičin,"},{"v":14,"t":"usta im puna kletve i grkosti;"},{"v":15,"t":"noge im hitre da krv proliju,"},{"v":16,"t":"razvaline i nevolja na njinim su putima,"},{"v":17,"t":"put mira oni ne poznaju,"},{"v":18,"t":"straha Božjega nemaju pred očima."},{"v":19,"t":"A znamo: što god Zakon veli, govori onima pod Zakonom, da svaka usta umuknu i sav svijet bude krivac pred Bogom."},{"v":20,"t":"Zato se po djelima Zakona nitko neće opravdati pred njim. Uistinu, po Zakonu - samo spoznaja grijeha!"},{"v":21,"t":"Sada se pak izvan Zakona očitovala pravednost Božja, posvjedočena Zakonom i Prorocima,"},{"v":22,"t":"pravednost Božja po vjeri Isusa Krista, prema svima koji vjeruju. Ne, nema razlike!"},{"v":23,"t":"Svi su zaista sagriješili i potrebna im je slava Božja;"},{"v":24,"t":"opravdani su besplatno, njegovom milošću po otkupljenju u Kristu Isusu."},{"v":25,"t":"Njega je Bog izložio da krvlju svojom bude Pomirilište po vjeri. Htio je tako očitovati svoju pravednost kojom je u svojoj božanskoj strpljivosti propuštao dotadašnje grijehe;"},{"v":26,"t":"htio je očitovati svoju pravednost u sadašnje vrijeme - da bude pravedan i da opravdava onoga koji je od vjere Isusove."},{"v":27,"t":"Gdje je dakle hvastanje? Isključeno je. Po kojem zakonu? Po zakonu djela? Ne, nego po zakonu vjere."},{"v":28,"t":"Smatramo zaista da se čovjek opravdava vjerom bez djela Zakona."},{"v":29,"t":"Ili je Bog samo Bog Židova? Nije li i pogana? Da, i pogana."},{"v":30,"t":"Jer jedan je Bog: on će opravdati obrezane zbog vjere i neobrezane po vjeri."},{"v":31,"t":"Obeskrepljujemo li dakle Zakon po vjeri? Nipošto! Naprotiv, Zakon utvrđujemo."}]},"4":{"fa":[{"v":1,"t":"پس چه چیز را بگوییم که پدر ما ابراهیم بحسب جسم یافت؟"},{"v":2,"t":"زیرا اگر ابراهیم به اعمال عادل شمرده شد، جای فخر دارد اما نه درنزد خدا."},{"v":3,"t":"زیرا کتاب چه می‌گوید؟ «ابراهیم به خدا ایمان آورد و آن برای او عدالت محسوب شد.»"},{"v":4,"t":"لکن برای کسی‌که عمل می‌کند، مزدش نه ازراه فیض بلکه از راه طلب محسوب می‌شود."},{"v":5,"t":"واما کسی‌که عمل نکند، بلکه ایمان آورد به او که بی‌دینان را عادل می‌شمارد، ایمان او عدالت محسوب می‌شود."},{"v":6,"t":"چنانکه داود نیز خوش حالی آن کس را ذکر می‌کند که خدا برای او عدالت محسوب می‌دارد، بدون اعمال:"},{"v":7,"t":"«خوشابحال کسانی که خطایای ایشان آمرزیده شد وگناهانشان مستور گردید؛"},{"v":8,"t":"خوشابحال کسی‌که خداوند گناه را به وی محسوب نفرماید.»"},{"v":9,"t":"پس آیا این خوشحالی بر اهل ختنه گفته شدیا برای نامختونان نیز؟ زیرا می‌گوییم ایمان ابراهیم به عدالت محسوب گشت."},{"v":10,"t":"پس در چه حالت محسوب شد، وقتی که او در ختنه بود یادر نامختونی؟ در ختنه نی، بلکه در نامختونی؛"},{"v":11,"t":"و علامت ختنه را یافت تا مهر باشد بر آن عدالت ایمانی که در نامختونی داشت، تا او همه نامختونان را که ایمان آورند پدر باشد تا عدالت برای ایشان هم محسوب شود؛"},{"v":12,"t":"و پدر اهل ختنه نیز یعنی آنانی را که نه فقط مختونند بلکه سالک هم می‌باشند بر آثار ایمانی که پدر ماابراهیم در نامختونی داشت."},{"v":13,"t":"زیرا به ابراهیم و ذریت او، وعده‌ای که اووارث جهان خواهد بود، از جهت شریعت داده نشد بلکه از عدالت ایمان."},{"v":14,"t":"زیرا اگر اهل شریعت وارث باشند، ایمان عاطل شد و وعده باطل."},{"v":15,"t":"زیرا که شریعت باعث غضب است، زیرا جایی که شریعت نیست تجاوز هم نیست."},{"v":16,"t":"و ازاین جهت از ایمان شد تا محض فیض باشد تاوعده برای همگی ذریت استوار شود نه مختص به ذریت شرعی بلکه به ذریت ایمانی ابراهیم نیزکه پدر جمیع ما است،"},{"v":17,"t":"(چنانکه مکتوب است که تو را پدر امت های بسیار ساخته‌ام )، در حضورآن خدایی که به او ایمان آورد که مردگان را زنده می‌کند و ناموجودات را به وجود می‌خواند؛"},{"v":18,"t":"که او در ناامیدی به امید ایمان آورد تا پدرامت های بسیار شود، برحسب آنچه گفته شد که «ذریت تو چنین خواهند بود.»"},{"v":19,"t":"و در ایمان کم قوت نشده، نظر کرد به بدن خود که در آن وقت مرده بود، چونکه قریب به صد ساله بود و به رحم مرده ساره."},{"v":20,"t":"و در وعده خدا از بی‌ایمانی شک ننمود، بلکه قوی الایمان گشته، خدا را تمجیدنمود،"},{"v":21,"t":"و یقین دانست که به وفای وعده خود نیزقادر است."},{"v":22,"t":"و از این جهت برای او عدالت محسوب شد."},{"v":23,"t":"ولکن اینکه برای وی محسوب شد، نه برای او فقط نوشته شد،"},{"v":24,"t":"بلکه برای ما نیزکه به ما محسوب خواهد شد، چون ایمان آوریم به او که خداوند ما عیسی را از مردگان برخیزانید،"},{"v":25,"t":"که به‌سبب گناهان ما تسلیم گردید و به‌سبب عادل شدن ما برخیزانیده شد."}],"en":[{"v":1,"t":"What then will we say that Abraham, our forefather, has found according to the flesh?"},{"v":2,"t":"For if Abraham was justified by works, he has something to boast about, but not toward God."},{"v":3,"t":"For what does the Scripture say? “Abraham believed God, and it was accounted to him for righteousness.”"},{"v":4,"t":"Now to him who works, the reward is not counted as grace, but as something owed."},{"v":5,"t":"But to him who doesn’t work, but believes in him who justifies the ungodly, his faith is accounted for righteousness."},{"v":6,"t":"Even as David also pronounces blessing on the man to whom God counts righteousness apart from works:"},{"v":7,"t":"“Blessed are they whose iniquities are forgiven, whose sins are covered."},{"v":8,"t":"Blessed is the man whom the Lord will by no means charge with sin.”"},{"v":9,"t":"Is this blessing then pronounced only on the circumcised, or on the uncircumcised also? For we say that faith was accounted to Abraham for righteousness."},{"v":10,"t":"How then was it counted? When he was in circumcision, or in uncircumcision? Not in circumcision, but in uncircumcision."},{"v":11,"t":"He received the sign of circumcision, a seal of the righteousness of the faith which he had while he was in uncircumcision, that he might be the father of all those who believe, though they might be in uncircumcision, that righteousness might also be accounted to them."},{"v":12,"t":"He is the father of circumcision to those who not only are of the circumcision, but who also walk in the steps of that faith of our father Abraham, which he had in uncircumcision."},{"v":13,"t":"For the promise to Abraham and to his offspring that he would be heir of the world wasn’t through the law, but through the righteousness of faith."},{"v":14,"t":"For if those who are of the law are heirs, faith is made void, and the promise is made of no effect."},{"v":15,"t":"For the law produces wrath; for where there is no law, neither is there disobedience."},{"v":16,"t":"For this cause it is of faith, that it may be according to grace, to the end that the promise may be sure to all the offspring, not to that only which is of the law, but to that also which is of the faith of Abraham, who is the father of us all."},{"v":17,"t":"As it is written, “I have made you a father of many nations.” This is in the presence of him whom he believed: God, who gives life to the dead, and calls the things that are not, as though they were."},{"v":18,"t":"Against hope, Abraham in hope believed, to the end that he might become a father of many nations, according to that which had been spoken, “So will your offspring be.”"},{"v":19,"t":"Without being weakened in faith, he didn’t consider his own body, already having been worn out, (he being about a hundred years old), and the deadness of Sarah’s womb."},{"v":20,"t":"Yet, looking to the promise of God, he didn’t waver through unbelief, but grew strong through faith, giving glory to God,"},{"v":21,"t":"and being fully assured that what he had promised, he was also able to perform."},{"v":22,"t":"Therefore it also was “credited to him for righteousness.”"},{"v":23,"t":"Now it was not written that it was accounted to him for his sake alone,"},{"v":24,"t":"but for our sake also, to whom it will be accounted, who believe in him who raised Jesus our Lord from the dead,"},{"v":25,"t":"who was delivered up for our trespasses, and was raised for our justification."}],"hr":[{"v":1,"t":"Što ćemo dakle reći? Što je Abraham, otac naš, našao po tijelu?"},{"v":2,"t":"Doista, ako je Abraham po djelima opravdan, ima se čime dičiti - ali ne pred Bogom."},{"v":3,"t":"Ta što veli Pismo? Povjerova Abraham Bogu i uračuna mu se u pravednost."},{"v":4,"t":"Onomu tko radi ne računa se plaća kao milost, nego kao dug."},{"v":5,"t":"Onomu tko ne radi, a vjeruje u Onoga koji opravdava bezbožnika, vjera se uračunava u pravednost,"},{"v":6,"t":"kao što i David blaženim proglašuje čovjeka kojemu Bog uračunava pravednost bez djela:"},{"v":7,"t":"Blaženi oni kojima je zločin otpušten, kojima je grijeh pokriven!"},{"v":8,"t":"Blago čovjeku komu Gospodin ne ubraja krivnju."},{"v":9,"t":"Ide li dakle ovo blaženstvo samo obrezane ili i neobrezane? Ta velimo: Vjera se Abrahamu uračuna u pravednost."},{"v":10,"t":"A kako mu se uračuna? Već obrezanu ili još neobrezanu? Ne obrezanu, nego neobrezanu!"},{"v":11,"t":"I znak obrezanja primi kao pečat pravednosti koju je po vjeri zadobio još neobrezan, da bude ocem svih vjernika: neobrezanih - te im se uračuna pravednost -"},{"v":12,"t":"i ocem obrezanih, ne onih koji su samo obrezani, nego onih koji uz to idu stopama vjere još neobrezana oca našeg Abrahama."},{"v":13,"t":"Doista, obećanje da će biti baštinik svijeta nije Abrahamu ili njegovu potomstvu dano na temelju nekog zakona, nego na temelju pravednosti vjere."},{"v":14,"t":"Jer ako su baštinici oni iz Zakona, prazna je vjera, jalovo obećanje."},{"v":15,"t":"Ta Zakon rađa gnjev; gdje pak nema Zakona, nema ni prekršaja."},{"v":16,"t":"Zato - zbog vjere da bude po milosti to obećanje zajamčeno svemu potomstvu, ne potomstvu samo po Zakonu, nego i po vjeri Abrahama, koji je otac svih nas -"},{"v":17,"t":"kao što je pisano: Ocem mnoštva naroda ja te postavljam - pred Onim komu povjerova, pred Bogom koji oživljuje mrtve i zove da bude ono što nije."},{"v":18,"t":"U nadi protiv svake nade povjerova Abraham da postane ocem naroda mnogih po onom što je rečeno: Toliko će biti tvoje potomstvo."},{"v":19,"t":"Nepokolebljivom vjerom promotri on tijelo svoje već obamrlo - bilo mu je blizu sto godina - i obamrlost krila Sarina."},{"v":20,"t":"Ali pred Božjim obećanjem nije nevjeran dvoumio, nego se vjerom ojačao davši slavu Bogu,"},{"v":21,"t":"posve uvjeren da on može učiniti što je obećao."},{"v":22,"t":"Zato mu se i uračuna u pravednost."},{"v":23,"t":"Ali nije samo za nj napisano: Uračuna mu se,"},{"v":24,"t":"nego i za nas kojima se ima uračunati, nama što vjerujemo u Onoga koji od mrtvih uskrisi Isusa, Gospodina našega,"},{"v":25,"t":"koji je predan za opačine naše i uskrišen radi našeg opravdanja."}]},"5":{"fa":[{"v":1,"t":"پس چونکه به ایمان عادل شمرده شدیم، نزد خدا سلامتی داریم بوساطت خداوندما عیسی مسیح،"},{"v":2,"t":"که به وساطت او دخول نیزیافته‌ایم بوسیله ایمان در آن فیضی که در آن پایداریم و به امید جلال خدا فخر می‌نماییم."},{"v":3,"t":"ونه این تنها بلکه در مصیبتها هم فخر می‌کنیم، چونکه می‌دانیم که مصیبت صبر را پیدا می‌کند،"},{"v":4,"t":"و صبر امتحان را و امتحان امید را."},{"v":5,"t":"و امید باعث شرمساری نمی شود زیرا که محبت خدا دردلهای ما به روح‌القدس که به ما عطا شد ریخته شده است."},{"v":6,"t":"زیرا هنگامی که ما هنوز ضعیف بودیم، در زمان معین، مسیح برای بیدینان وفات یافت."},{"v":7,"t":"زیرا بعید است که برای شخص عادل کسی بمیرد، هرچند در راه مرد نیکو ممکن است کسی نیز جرات کند که بمیرد."},{"v":8,"t":"لکن خدا محبت خود را در ما ثابت می‌کند از اینکه هنگامی که ماهنوز گناهکار بودیم، مسیح در راه ما مرد."},{"v":9,"t":"پس چقدر بیشتر الان که به خون او عادل شمرده شدیم، بوسیله او از غضب نجات خواهیم یافت."},{"v":10,"t":"زیرا اگر در حالتی که دشمن بودیم، بوساطت مرگ پسرش با خدا صلح داده شدیم، پس چقدربیشتر بعد از صلح یافتن بوساطت حیات او نجات خواهیم یافت."},{"v":11,"t":"و نه همین فقط بلکه در خدا هم فخر می‌کنیم بوسیله خداوند ما عیسی مسیح که بوساطت او الان صلح یافته‌ایم."},{"v":12,"t":"لهذا همچنان‌که بوساطت یک آدم گناه داخل جهان گردید و به گناه موت؛ و به اینگونه موت بر همه مردم طاری گشت، از آنجا که همه گناه کردند."},{"v":13,"t":"زیرا قبل از شریعت، گناه در جهان می‌بود، لکن گناه محسوب نمی شود در جایی که شریعت نیست."},{"v":14,"t":"بلکه از آدم تا موسی موت تسلط می‌داشت بر آنانی نیز که بر مثال تجاوز آدم که نمونه آن آینده است، گناه نکرده بودند."},{"v":15,"t":"و نه‌چنانکه خطا بود، همچنان نعمت نیز باشد. زیرااگر به خطای یک شخص بسیاری مردند، چقدرزیاده فیض خدا و آن بخششی که به فیض یک انسان، یعنی عیسی مسیح است، برای بسیاری افزون گردید."},{"v":16,"t":"و نه اینکه مثل آنچه از یک گناهکار سر زد، همچنان بخشش باشد؛ زیراحکم شد از یک برای قصاص لکن نعمت ازخطایای بسیار برای عدالت رسید."},{"v":17,"t":"زیرا اگر به‌سبب خطای یک نفر و بواسطه آن یک موت سلطنت کرد، چقدر بیشتر آنانی که افزونی فیض و بخشش عدالت را می‌پذیرند، در حیات سلطنت خواهند کرد بوسیله یک یعنی عیسی مسیح."},{"v":18,"t":"پس همچنان‌که به یک خطا حکم شد برجمیع مردمان برای قصاص، همچنین به یک عمل صالح بخشش شد بر جمیع مردمان برای عدالت حیات."},{"v":19,"t":"زیرا به همین قسمی که ازنافرمانی یک شخص بسیاری گناهکار شدند، همچنین نیز به اطاعت یک شخص بسیاری عادل خواهند گردید."},{"v":20,"t":"اما شریعت در میان آمد تاخطا زیاده شود. لکن جایی که گناه زیاده گشت، فیض بینهایت افزون گردید."},{"v":21,"t":"تا آنکه چنانکه گناه در موت سلطنت کرد، همچنین فیض نیزسلطنت نماید به عدالت برای حیات جاودانی بوساطت خداوند ما عیسی مسیح."}],"en":[{"v":1,"t":"Being therefore justified by faith, we have peace with God through our Lord Jesus Christ;"},{"v":2,"t":"through whom we also have our access by faith into this grace in which we stand. We rejoice in hope of the glory of God."},{"v":3,"t":"Not only this, but we also rejoice in our sufferings, knowing that suffering produces perseverance;"},{"v":4,"t":"and perseverance, proven character; and proven character, hope;"},{"v":5,"t":"and hope doesn’t disappoint us, because God’s love has been poured into our hearts through the Holy Spirit who was given to us."},{"v":6,"t":"For while we were yet weak, at the right time Christ died for the ungodly."},{"v":7,"t":"For one will hardly die for a righteous man. Yet perhaps for a good person someone would even dare to die."},{"v":8,"t":"But God commends his own love toward us, in that while we were yet sinners, Christ died for us."},{"v":9,"t":"Much more then, being now justified by his blood, we will be saved from God’s wrath through him."},{"v":10,"t":"For if while we were enemies, we were reconciled to God through the death of his Son, much more, being reconciled, we will be saved by his life."},{"v":11,"t":"Not only so, but we also rejoice in God through our Lord Jesus Christ, through whom we have now received the reconciliation."},{"v":12,"t":"Therefore, as sin entered into the world through one man, and death through sin, so death passed to all men because all sinned."},{"v":13,"t":"For until the law, sin was in the world; but sin is not charged when there is no law."},{"v":14,"t":"Nevertheless death reigned from Adam until Moses, even over those whose sins weren’t like Adam’s disobedience, who is a foreshadowing of him who was to come."},{"v":15,"t":"But the free gift isn’t like the trespass. For if by the trespass of the one the many died, much more did the grace of God and the gift by the grace of the one man, Jesus Christ, abound to the many."},{"v":16,"t":"The gift is not as through one who sinned; for the judgment came by one to condemnation, but the free gift followed many trespasses to justification."},{"v":17,"t":"For if by the trespass of the one, death reigned through the one; so much more will those who receive the abundance of grace and of the gift of righteousness reign in life through the one, Jesus Christ."},{"v":18,"t":"So then as through one trespass, all men were condemned; even so through one act of righteousness, all men were justified to life."},{"v":19,"t":"For as through the one man’s disobedience many were made sinners, even so through the obedience of the one, many will be made righteous."},{"v":20,"t":"The law came in that the trespass might abound; but where sin abounded, grace abounded more exceedingly,"},{"v":21,"t":"that as sin reigned in death, even so grace might reign through righteousness to eternal life through Jesus Christ our Lord."}],"hr":[{"v":1,"t":"Opravdani dakle vjerom, u miru smo s Bogom po Gospodinu našem Isusu Kristu."},{"v":2,"t":"Po njemu imamo u vjeri i pristup u ovu milost u kojoj stojimo i dičimo se nadom slave Božje."},{"v":3,"t":"I ne samo to! Mi se dičimo i u nevoljama jer znamo: nevolja rađa postojanošću,"},{"v":4,"t":"postojanost prokušanošću, prokušanost nadom."},{"v":5,"t":"Nada pak ne postiđuje. Ta ljubav je Božja razlivena u srcima našim po Duhu Svetom koji nam je dan!"},{"v":6,"t":"Doista, dok mi još bijasmo nemoćni, Krist je, već u to vrijeme, za nas bezbožnike umro."},{"v":7,"t":"Zbilja, jedva bi tko za pravedna umro; možda bi se za dobra tko i odvažio umrijeti."},{"v":8,"t":"A Bog pokaza ljubav svoju prema nama ovako: dok još bijasmo grešnici, Krist za nas umrije."},{"v":9,"t":"Koliko li ćemo se više sada, pošto smo opravdani krvlju njegovom, spasiti po njemu od srdžbe?"},{"v":10,"t":"Doista, ako se s Bogom pomirismo po smrti Sina njegova dok još bijasmo neprijatelji, mnogo ćemo se više, pomireni, spasiti životom njegovim."},{"v":11,"t":"I ne samo to! Dičimo se u Bogu po Gospodinu našemu Isusu Kristu po kojem zadobismo pomirenje."},{"v":12,"t":"Zbog toga, kao što po jednom Čovjeku uđe u svijet grijeh i po grijehu smrt, i time što svi sagriješiše, na sve ljude prijeđe smrt..."},{"v":13,"t":"Doista, do Zakona bilo je grijeha u svijetu, ali se grijeh ne ubraja kad nema zakona."},{"v":14,"t":"Da, ali smrt je od Adama do Mojsija doista kraljevala i nad onima koji ne sagriješiše prekršajem sličnim kao Adam, koji je pralik Onoga koji ima doći."},{"v":15,"t":"Ali s darom nije kao s grijehom. Jer ako su grijehom jednoga mnogi umrli, mnogo se obilatije na sve razlila milost Božja, milost darovana u jednom čovjeku, Isusu Kristu."},{"v":16,"t":"I dar - to nije kao kad je ono jedan sagriješio: jer presuda nakon jednoga grijeha posta osudom, a dar nakon mnogih grijeha - opravdanjem."},{"v":17,"t":"Uistinu, ako grijehom jednoga smrt zakraljeva - po jednome, mnogo će više oni koji primaju izobilje milosti i dara pravednosti kraljevati u životu - po Jednome, Isusu Kristu."},{"v":18,"t":"Dakle, grijeh jednoga - svim ljudima na osudu, tako i pravednost Jednoga - svim ljudima na opravdanje, na život!"},{"v":19,"t":"Doista, kao što su neposluhom jednoga čovjeka mnogi postali grešnici tako će i posluhom Jednoga mnogi postati pravednici."},{"v":20,"t":"A zakon nadođe da se umnoži grijeh. Ali gdje se umnožio grijeh, nadmoćno izobilova milost:"},{"v":21,"t":"kao što grijeh zakraljeva smrću, da tako i milost kraljuje pravednošću za život vječni po Isusu Kristu Gospodinu našemu."}]},"6":{"fa":[{"v":1,"t":"پس چه گوییم؟ آیا در گناه بمانیم تا فیض افزون گردد؟"},{"v":2,"t":"حاشا! مایانی که از گناه مردیم، چگونه دیگر در آن زیست کنیم؟"},{"v":3,"t":"یانمی دانید که جمیع ما که در مسیح عیسی تعمیدیافتیم، در موت او تعمید یافتیم؟"},{"v":4,"t":"پس چونکه در موت او تعمید یافتیم، با او دفن شدیم تا آنکه به همین قسمی که مسیح به جلال پدر از مردگان برخاست، ما نیز در تازگی حیات رفتار نماییم."},{"v":5,"t":"زیرا اگر بر مثال موت او متحد گشتیم، هرآینه در قیامت وی نیز چنین خواهیم شد."},{"v":6,"t":"زیرا این رامی دانیم که انسانیت کهنه ما با او مصلوب شد تاجسد گناه معدوم گشته، دیگر گناه را بندگی نکنیم."},{"v":7,"t":"زیرا هر‌که مرد، از گناه مبرا شده است."},{"v":8,"t":"پس هرگاه با مسیح مردیم، یقین می‌دانیم که با اوزیست هم خواهیم کرد."},{"v":9,"t":"زیرا می‌دانیم که چون مسیح از مردگان برخاست، دیگر نمی میرد و بعداز این موت بر او تسلطی ندارد."},{"v":10,"t":"زیرا به آنچه مرد یک مرتبه برای گناه مرد و به آنچه زندگی می‌کند، برای خدا زیست می‌کند."},{"v":11,"t":"همچنین شما نیز خود را برای گناه مرده انگارید، اما برای خدا در مسیح عیسی زنده."},{"v":12,"t":"پس گناه در جسم فانی شما حکمرانی نکند تا هوسهای آن را اطاعت نمایید،"},{"v":13,"t":"واعضای خود را به گناه مسپارید تا آلات ناراستی شوند، بلکه خود را از مردگان زنده شده به خداتسلیم کنید و اعضای خود را تا آلات عدالت برای خدا باشند."},{"v":14,"t":"زیرا گناه بر شما سلطنت نخواهد کرد، چونکه زیر شریعت نیستید بلکه زیرفیض."},{"v":15,"t":"پس چه گوییم؟ آیا گناه بکنیم از آنرو که زیر شریعت نیستیم بلکه زیر فیض؟ حاشا!"},{"v":16,"t":"آیانمی دانید که اگر خویشتن را به بندگی کسی تسلیم کرده، او را اطاعت نمایید، شما آنکس را که او رااطاعت می‌کنید بنده هستید، خواه گناه را برای مرگ، خواه اطاعت را برای عدالت."},{"v":17,"t":"اما شکرخدا را که هرچند غلامان گناه می‌بودید، لیکن الان از دل، مطیع آن صورت تعلیم گردیده‌اید که به آن سپرده شده‌اید."},{"v":18,"t":"و از گناه آزاد شده، غلامان عدالت گشته‌اید."},{"v":19,"t":"بطور انسان، به‌سبب ضعف جسم شما سخن می‌گویم، زیرا همچنان‌که اعضای خود را بندگی نجاست و گناه برای گناه سپردید، همچنین الان نیز اعضای خود را به بندگی عدالت برای قدوسیت بسپارید."},{"v":20,"t":"زیراهنگامی که غلامان گناه می‌بودید از عدالت آزادمی بودید."},{"v":21,"t":"پس آن وقت چه ثمر داشتید از آن کارهایی که الان از آنها شرمنده‌اید که انجام آنهاموت است؟"},{"v":22,"t":"اما الحال چونکه از گناه آزاد شده و غلامان خدا گشته‌اید، ثمر خود را برای قدوسیت می‌آورید که عاقبت آن، حیات جاودانی است."},{"v":23,"t":"زیرا که مزد گناه موت است، اما نعمت خدا حیات جاودانی در خداوند ماعیسی مسیح."}],"en":[{"v":1,"t":"What shall we say then? Shall we continue in sin, that grace may abound?"},{"v":2,"t":"May it never be! We who died to sin, how could we live in it any longer?"},{"v":3,"t":"Or don’t you know that all of us who were baptized into Christ Jesus were baptized into his death?"},{"v":4,"t":"We were buried therefore with him through baptism into death, that just as Christ was raised from the dead through the glory of the Father, so we also might walk in newness of life."},{"v":5,"t":"For if we have become united with him in the likeness of his death, we will also be part of his resurrection;"},{"v":6,"t":"knowing this, that our old man was crucified with him, that the body of sin might be done away with, so that we would no longer be in bondage to sin."},{"v":7,"t":"For he who has died has been freed from sin."},{"v":8,"t":"But if we died with Christ, we believe that we will also live with him,"},{"v":9,"t":"knowing that Christ, being raised from the dead, dies no more. Death no longer has dominion over him!"},{"v":10,"t":"For the death that he died, he died to sin one time; but the life that he lives, he lives to God."},{"v":11,"t":"Thus consider yourselves also to be dead to sin, but alive to God in Christ Jesus our Lord."},{"v":12,"t":"Therefore don’t let sin reign in your mortal body, that you should obey it in its lusts."},{"v":13,"t":"Also, do not present your members to sin as instruments of unrighteousness, but present yourselves to God as alive from the dead, and your members as instruments of righteousness to God."},{"v":14,"t":"For sin will not have dominion over you, for you are not under law, but under grace."},{"v":15,"t":"What then? Shall we sin because we are not under law but under grace? May it never be!"},{"v":16,"t":"Don’t you know that when you present yourselves as servants and obey someone, you are the servants of whomever you obey, whether of sin to death, or of obedience to righteousness?"},{"v":17,"t":"But thanks be to God that, whereas you were bondservants of sin, you became obedient from the heart to that form of teaching to which you were delivered."},{"v":18,"t":"Being made free from sin, you became bondservants of righteousness."},{"v":19,"t":"I speak in human terms because of the weakness of your flesh; for as you presented your members as servants to uncleanness and to wickedness upon wickedness, even so now present your members as servants to righteousness for sanctification."},{"v":20,"t":"For when you were servants of sin, you were free from righteousness."},{"v":21,"t":"What fruit then did you have at that time in the things of which you are now ashamed? For the end of those things is death."},{"v":22,"t":"But now, being made free from sin and having become servants of God, you have your fruit of sanctification and the result of eternal life."},{"v":23,"t":"For the wages of sin is death, but the free gift of God is eternal life in Christ Jesus our Lord."}],"hr":[{"v":1,"t":"Što ćemo dakle reći? Da ostanemo u grijehu da milost izobiluje?"},{"v":2,"t":"Nipošto! Jednom umrli grijehu, kako da još živimo u njemu?"},{"v":3,"t":"Ili zar ne znate: koji smo god kršteni u Krista Isusa, u smrt smo njegovu kršteni."},{"v":4,"t":"Krštenjem smo dakle zajedno s njime ukopani u smrt da kao što Krist slavom Očevom bi uskrišen od mrtvih, i mi tako hodimo u novosti života."},{"v":5,"t":"Ako smo doista s njime srasli po sličnosti smrti njegovoj, očito ćemo srasti i po sličnosti njegovu uskrsnuću."},{"v":6,"t":"Ovo znamo: naš je stari čovjek zajedno s njim raspet da onemoća ovo grešno tijelo te više ne robujemo grijehu."},{"v":7,"t":"Ta tko umre, opravdan je od grijeha."},{"v":8,"t":"Pa ako umrijesmo s Kristom, vjerujemo da ćemo i živjeti zajedno s njime."},{"v":9,"t":"Znamo doista: Krist uskrišen od mrtvih, više ne umire, smrt njime više ne gospoduje."},{"v":10,"t":"Što umrije, umrije grijehu jednom zauvijek; a što živi, živi Bogu."},{"v":11,"t":"Tako i vi: smatrajte sebe mrtvima grijehu, a živima Bogu u Kristu Isusu!"},{"v":12,"t":"Neka dakle ne kraljuje grijeh u vašem smrtnom tijelu da slušate njegove požude;"},{"v":13,"t":"i ne predajite grijehu udova svojih za oružje nepravde, nego sebe, od mrtvih oživjele, predajte Bogu i udove svoje dajte Bogu za oružje pravednosti."},{"v":14,"t":"Valjda grijeh neće vama gospodovati! Ta niste pod Zakonom nego pod milošću!"},{"v":15,"t":"Što dakle? Da griješimo jer nismo pod Zakonom nego pod milošću? Nipošto!"},{"v":16,"t":"Ne znate li: ako se komu predate za robove, na poslušnost, robovi ste onoga koga slušate: bilo grijeha - na smrt, bilo poslušnosti - na pravednost."},{"v":17,"t":"Bijaste robovi grijeha, ali ste, hvala Bogu, od srca poslušali ono pravilo nauka kojemu ste povjereni;"},{"v":18,"t":"da, oslobođeni grijeha, postadoste sluge pravednosti."},{"v":19,"t":"Po ljudsku govorim zbog vaše ljudske slabosti: kao što nekoć predadoste udove svoje za robove nečistoći i bezakonju - do bezakonja, tako sada predajte udove svoje za robove pravednosti - do posvećenja."},{"v":20,"t":"Uistinu, kad bijaste robovi grijeha, “slobodni” bijaste od pravednosti."},{"v":21,"t":"Pa kakav ste plod onda imali? Onoga se sada stidite jer svršetak je tomu - smrt."},{"v":22,"t":"Sada pak pošto ste oslobođeni grijeha i postali sluge Božje, imate plod svoj za posvećenje, a svršetak - život vječni."},{"v":23,"t":"Jer plaća je grijeha smrt, a dar Božji jest život vječni u Kristu Isusu, Gospodinu našem."}]},"7":{"fa":[{"v":1,"t":"ای برادران آیا نمی دانید (زیرا که با عارفین شریعت سخن می‌گویم ) که مادامی که انسان زنده است، شریعت بر وی حکمرانی دارد؟"},{"v":2,"t":"زیرا زن منکوحه برحسب شریعت به شوهرزنده بسته است، اما هرگاه شوهرش بمیرد، ازشریعت شوهرش آزاد شود."},{"v":3,"t":"پس مادامی که شوهرش حیات دارد، اگر به مرد دیگر پیوندد، زانیه خوانده می‌شود. لکن هرگاه شوهرش بمیرد، از آن شریعت آزاد است که اگر به شوهری دیگرداده شود، زانیه نباشد."},{"v":4,"t":"بنابراین، ای برادران من، شما نیز بوساطت جسد مسیح برای شریعت مرده شدید تا خود رابه دیگری پیوندید، یعنی با او که از مردگان برخاست، تا بجهت خدا ثمر آوریم."},{"v":5,"t":"زیرا وقتی که در جسم بودیم، هوسهای گناهانی که ازشریعت بود، در اعضای ما عمل می‌کرد تا بجهت موت ثمر آوریم."},{"v":6,"t":"اما الحال چون برای آن چیزی که در آن بسته بودیم مردیم، از شریعت آزاد شدیم، بحدی که در تازگی روح بندگی می‌کنیم نه در کهنگی حرف."},{"v":7,"t":"پس چه گوییم؟ آیا شریعت گناه است؟ حاشا! بلکه گناه را جز به شریعت ندانستیم. زیراکه شهوت را نمی دانستم، اگر شریعت نمی گفت که طمع مورز."},{"v":8,"t":"لکن گناه از حکم فرصت جسته، هر قسم طمع را در من پدید آورد، زیرا بدون شریعت گناه مرده است."},{"v":9,"t":"و من از قبل بدون شریعت زنده می‌بودم؛ لکن چون حکم آمد، گناه زنده گشت و من مردم."},{"v":10,"t":"و آن حکمی که برای حیات بود، همان مرا باعث موت گردید."},{"v":11,"t":"زیراگناه از حکم فرصت یافته، مرا فریب داد و به آن مرا کشت."},{"v":12,"t":"خلاصه شریعت مقدس است و حکم مقدس و عادل و نیکو."},{"v":13,"t":"پس آیا نیکویی برای من موت گردید؟ حاشا! بلکه گناه، تا گناه بودنش ظاهر شود. بوسیله نیکویی برای من باعث مرگ شد تا آنکه گناه به‌سبب حکم بغایت خبیث شود."},{"v":14,"t":"زیرا می‌دانیم که شریعت روحانی است، لکن من جسمانی و زیر گناه فروخته شده هستم،"},{"v":15,"t":"که آنچه می‌کنم نمی دانم زیرا آنچه می‌خواهم نمی کنم بلکه کاری را که از آن نفرت دارم بجامی آورم."},{"v":16,"t":"پس هرگاه کاری را که نمی خواهم به‌جا می‌آورم، شریعت را تصدیق می‌کنم که نیکوست."},{"v":17,"t":"و الحال من دیگر فاعل آن نیستم بلکه آن گناهی که در من ساکن است."},{"v":18,"t":"زیرامی دانم که در من یعنی در جسدم هیچ نیکویی ساکن نیست، زیرا که اراده در من حاضر است اماصورت نیکو کردن نی."},{"v":19,"t":"زیرا آن نیکویی را که می‌خواهم نمی کنم، بلکه بدی را که نمی خواهم می‌کنم."},{"v":20,"t":"پس چون آنچه را نمی خواهم می‌کنم، من دیگر فاعل آن نیستم بلکه گناه که در من ساکن است."},{"v":21,"t":"لهذا این شریعت را می‌یابم که وقتی که می‌خواهم نیکویی کنم بدی نزد من حاضر است."},{"v":22,"t":"زیرا برحسب انسانیت باطنی به شریعت خداخشنودم."},{"v":23,"t":"لکن شریعتی دیگر در اعضای خودمی بینم که با شریعت ذهن من منازعه می‌کند و مرااسیر می‌سازد به آن شریعت گناه که در اعضای من است."},{"v":24,"t":"وای بر من که مرد شقی‌ای هستم! کیست که مرا از جسم این موت رهایی بخشد؟"},{"v":25,"t":"خدا راشکر می‌کنم بوساطت خداوند ما عیسی مسیح. خلاصه اینکه من به ذهن خود شریعت خدا رابندگی می‌کنم و اما به جسم خود شریعت گناه را."}],"en":[{"v":1,"t":"Or don’t you know, brothers (for I speak to men who know the law), that the law has dominion over a man for as long as he lives?"},{"v":2,"t":"For the woman that has a husband is bound by law to the husband while he lives, but if the husband dies, she is discharged from the law of the husband."},{"v":3,"t":"So then if, while the husband lives, she is joined to another man, she would be called an adulteress. But if the husband dies, she is free from the law, so that she is no adulteress, though she is joined to another man."},{"v":4,"t":"Therefore, my brothers, you also were made dead to the law through the body of Christ, that you would be joined to another, to him who was raised from the dead, that we might produce fruit to God."},{"v":5,"t":"For when we were in the flesh, the sinful passions which were through the law worked in our members to bring out fruit to death."},{"v":6,"t":"But now we have been discharged from the law, having died to that in which we were held; so that we serve in newness of the spirit, and not in oldness of the letter."},{"v":7,"t":"What shall we say then? Is the law sin? May it never be! However, I wouldn’t have known sin except through the law. For I wouldn’t have known coveting unless the law had said, “You shall not covet.”"},{"v":8,"t":"But sin, finding occasion through the commandment, produced in me all kinds of coveting. For apart from the law, sin is dead."},{"v":9,"t":"I was alive apart from the law once, but when the commandment came, sin revived and I died."},{"v":10,"t":"The commandment which was for life, this I found to be for death;"},{"v":11,"t":"for sin, finding occasion through the commandment, deceived me, and through it killed me."},{"v":12,"t":"Therefore the law indeed is holy, and the commandment holy, righteous, and good."},{"v":13,"t":"Did then that which is good become death to me? May it never be! But sin, that it might be shown to be sin, was producing death in me through that which is good; that through the commandment sin might become exceedingly sinful."},{"v":14,"t":"For we know that the law is spiritual, but I am fleshly, sold under sin."},{"v":15,"t":"For I don’t understand what I am doing. For I don’t practice what I desire to do; but what I hate, that I do."},{"v":16,"t":"But if what I don’t desire, that I do, I consent to the law that it is good."},{"v":17,"t":"So now it is no more I that do it, but sin which dwells in me."},{"v":18,"t":"For I know that in me, that is, in my flesh, dwells no good thing. For desire is present with me, but I don’t find it doing that which is good."},{"v":19,"t":"For the good which I desire, I don’t do; but the evil which I don’t desire, that I practice."},{"v":20,"t":"But if what I don’t desire, that I do, it is no more I that do it, but sin which dwells in me."},{"v":21,"t":"I find then the law that, while I desire to do good, evil is present."},{"v":22,"t":"For I delight in God’s law after the inward person,"},{"v":23,"t":"but I see a different law in my members, warring against the law of my mind, and bringing me into captivity under the law of sin which is in my members."},{"v":24,"t":"What a wretched man I am! Who will deliver me out of the body of this death?"},{"v":25,"t":"I thank God through Jesus Christ, our Lord! So then with the mind, I myself serve God’s law, but with the flesh, sin’s law."}],"hr":[{"v":1,"t":"Ili zar ne znate, braćo - poznavaocima zakona govorim - da zakon gospodari čovjekom samo za vrijeme njegova života."},{"v":2,"t":"Doista, udana je žena vezana zakonom dok joj muž živi; umre li joj muž, riješena je zakona o mužu."},{"v":3,"t":"Dakle: dok joj muž živi, zvat će se, očito, preljubnicom pođe li za drugoga. Ako li joj pak muž umre, slobodna je od zakona te nije preljubnica pođe li za drugoga."},{"v":4,"t":"Tako, braćo moja, i vi po tijelu Kristovu umrijeste Zakonu da pripadnete drugomu, Onomu koji je od mrtvih uskrišen, te plodove donosimo Bogu."},{"v":5,"t":"Doista, dok bijasmo u tijelu, grešne su strasti, Zakonom izazvane, djelovale u našim udovima te smrti donosile plodove;"},{"v":6,"t":"sada pak umrijevši onomu što nas je sputavalo, riješeni smo Zakona te služimo u novosti Duha, a ne u stareži slova."},{"v":7,"t":"Što ćemo dakle reći? Je li Zakon grijeh? Nipošto! Nego: grijeha ne spoznah doli po Zakonu jer za požudu ne bih znao da Zakon nije govorio: Ne poželi!"},{"v":8,"t":"A grijeh je, uhvativši priliku, po zapovijedi u meni prouzročio svakovrsnu požudu. Ta bez zakona grijeh je mrtav."},{"v":9,"t":"Da, ja sam nekoć živio bez zakona. Ali kad je došla zapovijed, grijeh oživje."},{"v":10,"t":"Ja pak umrijeh i ustanovi se: zapovijed dana za život bi mi na smrt."},{"v":11,"t":"Doista grijeh, uhvativši priliku, zapovijeđu me zavede, njome me i ubi."},{"v":12,"t":"Tako: Zakon je svet, i zapovijed je sveta, i pravedna, i dobra."},{"v":13,"t":"Pa zar se to dobro meni u smrt prometnu? Nipošto! Nego: grijeh, da se grijehom očituje, po tom dobru uzrokuje mi smrt - da grijeh po zapovijedi postane najvećim grešnikom."},{"v":14,"t":"Zakon je, znamo, duhovan; ja sam pak tjelesan, prodan pod grijeh."},{"v":15,"t":"Zbilja ne razumijem što radim: ta ne činim ono što bih htio, nego što mrzim - to činim."},{"v":16,"t":"Ako li pak činim što ne bih htio, slažem se sa Zakonom, priznajem da je dobar."},{"v":17,"t":"Onda to ne činim više ja, nego grijeh koji prebiva u meni."},{"v":18,"t":"Doista znam da dobro ne prebiva u meni, to jest u mojem tijelu. Uistinu: htjeti mi ide, ali ne i činiti dobro."},{"v":19,"t":"Ta ne činim dobro koje bih htio, nego zlo koje ne bih htio - to činim."},{"v":20,"t":"Ako li pak činim ono što ne bih htio, nipošto to ne radim ja, nego grijeh koji prebiva u meni."},{"v":21,"t":"Nalazim dakle ovaj zakon: kad bih htio činiti dobro, nameće mi se zlo."},{"v":22,"t":"Po nutarnjem čovjeku s užitkom se slažem sa Zakonom Božjim,"},{"v":23,"t":"ali opažam u svojim udovima drugi zakon koji vojuje protiv zakona uma moga i zarobljuje me zakonom grijeha koji je u mojim udovima."},{"v":24,"t":"Jadan li sam ja čovjek! Tko će me istrgnuti iz ovoga tijela smrtonosnoga?"},{"v":25,"t":"Hvala Bogu po Isusu Kristu Gospodinu našem! Ja, dakle, umom ja služim zakonu Božjemu, a tijelom zakonu grijeha."}]},"8":{"fa":[{"v":1,"t":"پس هیچ قصاص نیست بر آنانی که درمسیح عیسی هستند."},{"v":2,"t":"زیرا که شریعت روح حیات در مسیح عیسی مرا از شریعت گناه وموت آزاد گردانید."},{"v":3,"t":"زیرا آنچه از شریعت محال بود، چونکه به‌سبب جسم ضعیف بود، خدا پسرخود را در شبیه جسم گناه و برای گناه فرستاده، برگناه در جسم فتوا داد،"},{"v":4,"t":"تا عدالت شریعت کامل گردد در مایانی که نه بحسب جسم بلکه برحسب روح رفتار می‌کنیم."},{"v":5,"t":"زیرا آنانی که برحسب جسم هستند، درچیزهای جسم تفکر می‌کنند و اما آنانی که برحسب روح هستند در چیزهای روح."},{"v":6,"t":"از آن جهت که تفکر جسم موت است، لکن تفکر روح حیات و سلامتی است."},{"v":7,"t":"زانرو که تفکر جسم دشمنی خدا است، چونکه شریعت خدا رااطاعت نمی کند، زیرا نمی تواند هم بکند."},{"v":8,"t":"وکسانی که جسمانی هستند، نمی توانند خدا راخشنود سازند."},{"v":9,"t":"لکن شما در جسم نیستید بلکه در روح، هرگاه روح خدا در شما ساکن باشد؛ وهرگاه کسی روح مسیح را ندارد وی از آن اونیست."},{"v":10,"t":"و اگر مسیح در شما است، جسم به‌سبب گناه مرده است و اما روح، به‌سبب عدالت، حیات‌است."},{"v":11,"t":"و اگر روح او که عیسی را ازمردگان برخیزانید در شما ساکن باشد، او که مسیح را از مردگان برخیزانید، بدنهای فانی شمارا نیز زنده خواهد ساخت به روح خود که در شماساکن است."},{"v":12,"t":"بنابراین‌ای برادران، مدیون جسم نیستیم تابرحسب جسم زیست نماییم."},{"v":13,"t":"زیرا اگربرحسب جسم زیست کنید، هرآینه خواهید مرد. لکن اگر افعال بدن را بوسیله روح بکشید، همانا خواهید زیست."},{"v":14,"t":"زیرا همه کسانی که از روح خدا هدایت می‌شوند، ایشان پسران خدایند."},{"v":15,"t":"از آنرو که روح بندگی را نیافته‌اید تا باز ترسان شوید بلکه روح پسر‌خواندگی را یافته‌اید که به آن ابا یعنی‌ای پدر ندا می‌کنیم."},{"v":16,"t":"همان روح برروحهای ما شهادت می‌دهد که فرزندان خداهستیم."},{"v":17,"t":"و هرگاه فرزندانیم، وارثان هم هستیم یعنی ورثه خدا و هم‌ارث با مسیح، اگر شریک مصیبتهای او هستیم تا در جلال وی نیز شریک باشیم."},{"v":18,"t":"زیرا یقین می‌دانم که دردهای زمان حاضرنسبت به آن جلالی که در ما ظاهر خواهد شد هیچ است."},{"v":19,"t":"زیرا که انتظار خلقت، منتظر ظهورپسران خدا می‌باشد،"},{"v":20,"t":"زیرا خلقت، مطیع بطالت شد، نه به اراده خود، بلکه بخاطر او که آن را مطیع گردانید،"},{"v":21,"t":"در امید که خود خلقت نیز از قیدفساد خلاصی خواهد یافت تا در آزادی جلال فرزندان خدا شریک شود."},{"v":22,"t":"زیرا می‌دانیم که تمام خلقت تا الان با هم در آه کشیدن و درد زه می‌باشند."},{"v":23,"t":"و نه این فقط، بلکه ما نیز که نوبر روح را یافته‌ایم، در خود آه می‌کشیم در انتظارپسرخواندگی یعنی خلاصی جسم خود."},{"v":24,"t":"زیراکه به امید نجات یافتیم، لکن چون امید دیده شد، دیگر امید نیست، زیرا آنچه کسی بیند چرا دیگردر امید آن باشد؟"},{"v":25,"t":"اما اگر امید چیزی را داریم که نمی بینیم، با صبر انتظار آن می‌کشیم."},{"v":26,"t":"و همچنین روح نیز ضعف ما را مددمی کند، زیرا که آنچه دعا کنیم بطوری که می‌بایدنمی دانیم، لکن خود روح برای ما شفاعت می‌کند به ناله هایی که نمی شود بیان کرد."},{"v":27,"t":"و او که تفحص کننده دلهاست، فکر روح را می‌داند زیراکه او برای مقدسین برحسب اراده خدا شفاعت می‌کند."},{"v":28,"t":"و می‌دانیم که بجهت آنانی که خدا رادوست می‌دارند و بحسب اراده او خوانده شده‌اند، همه‌چیزها برای خیریت (ایشان ) با هم در کار می‌باشند."},{"v":29,"t":"زیرا آنانی را که از قبل شناخت، ایشان را نیز پیش معین فرمود تا به صورت پسرش متشکل شوند تا او نخست زاده ازبرادران بسیار باشد."},{"v":30,"t":"و آنانی را که از قبل معین فرمود، ایشان را هم خواند و آنانی را که خواندایشان را نیز عادل گردانید و آنانی را که عادل گردانید، ایشان را نیز جلال داد."},{"v":31,"t":"پس به این چیزها چه گوییم؟ هرگاه خدا باما است کیست به ضد ما؟"},{"v":32,"t":"او که پسر خود رادریغ نداشت، بلکه او را در راه جمیع ما تسلیم نمود، چگونه با وی همه‌چیز را به ما نخواهدبخشید؟"},{"v":33,"t":"کیست که بر برگزیدگان خدا مدعی شود؟ آیا خدا که عادل کننده است؟"},{"v":34,"t":"کیست که بر ایشان فتوا دهد؟ آیا مسیح که مرد بلکه نیزبرخاست، آنکه به‌دست راست خدا هم هست وما را نیز شفاعت می‌کند؟"},{"v":35,"t":"کیست که ما را ازمحبت مسیح جدا سازد؟ آیا مصیبت یا دلتنگی یاجفا یا قحط یا عریانی یا خطر یا شمشیر؟"},{"v":36,"t":"چنانکه مکتوب است که «بخاطر تو تمام روزکشته و مثل گوسفندان ذبحی شمرده می‌شویم.»"},{"v":37,"t":"بلکه در همه این امور از حد زیاده نصرت یافتیم، بوسیله او که ما را محبت نمود."},{"v":38,"t":"زیرایقین می‌دانم که نه موت و نه حیات و نه فرشتگان و نه روسا و نه قدرتها و نه چیزهای حال و نه چیزهای آینده"},{"v":39,"t":"و نه بلندی و نه پستی و نه هیچ مخلوق دیگر قدرت خواهد داشت که ما را ازمحبت خدا که در خداوند ما مسیح عیسی است جدا سازد."}],"en":[{"v":1,"t":"There is therefore now no condemnation to those who are in Christ Jesus, who don’t walk according to the flesh, but according to the Spirit."},{"v":2,"t":"For the law of the Spirit of life in Christ Jesus made me free from the law of sin and of death."},{"v":3,"t":"For what the law couldn’t do, in that it was weak through the flesh, God did, sending his own Son in the likeness of sinful flesh and for sin, he condemned sin in the flesh,"},{"v":4,"t":"that the ordinance of the law might be fulfilled in us who don’t walk according to the flesh, but according to the Spirit."},{"v":5,"t":"For those who live according to the flesh set their minds on the things of the flesh, but those who live according to the Spirit, the things of the Spirit."},{"v":6,"t":"For the mind of the flesh is death, but the mind of the Spirit is life and peace;"},{"v":7,"t":"because the mind of the flesh is hostile toward God, for it is not subject to God’s law, neither indeed can it be."},{"v":8,"t":"Those who are in the flesh can’t please God."},{"v":9,"t":"But you are not in the flesh but in the Spirit, if it is so that the Spirit of God dwells in you. But if any man doesn’t have the Spirit of Christ, he is not his."},{"v":10,"t":"If Christ is in you, the body is dead because of sin, but the spirit is alive because of righteousness."},{"v":11,"t":"But if the Spirit of him who raised up Jesus from the dead dwells in you, he who raised up Christ Jesus from the dead will also give life to your mortal bodies through his Spirit who dwells in you."},{"v":12,"t":"So then, brothers, we are debtors, not to the flesh, to live after the flesh."},{"v":13,"t":"For if you live after the flesh, you must die; but if by the Spirit you put to death the deeds of the body, you will live."},{"v":14,"t":"For as many as are led by the Spirit of God, these are children of God."},{"v":15,"t":"For you didn’t receive the spirit of bondage again to fear, but you received the Spirit of adoption, by whom we cry, “Abba! Father!”"},{"v":16,"t":"The Spirit himself testifies with our spirit that we are children of God;"},{"v":17,"t":"and if children, then heirs—heirs of God and joint heirs with Christ, if indeed we suffer with him, that we may also be glorified with him."},{"v":18,"t":"For I consider that the sufferings of this present time are not worthy to be compared with the glory which will be revealed toward us."},{"v":19,"t":"For the creation waits with eager expectation for the children of God to be revealed."},{"v":20,"t":"For the creation was subjected to vanity, not of its own will, but because of him who subjected it, in hope"},{"v":21,"t":"that the creation itself also will be delivered from the bondage of decay into the liberty of the glory of the children of God."},{"v":22,"t":"For we know that the whole creation groans and travails in pain together until now."},{"v":23,"t":"Not only so, but ourselves also, who have the first fruits of the Spirit, even we ourselves groan within ourselves, waiting for adoption, the redemption of our body."},{"v":24,"t":"For we were saved in hope, but hope that is seen is not hope. For who hopes for that which he sees?"},{"v":25,"t":"But if we hope for that which we don’t see, we wait for it with patience."},{"v":26,"t":"In the same way, the Spirit also helps our weaknesses, for we don’t know how to pray as we ought. But the Spirit himself makes intercession for us with groanings which can’t be uttered."},{"v":27,"t":"He who searches the hearts knows what is on the Spirit’s mind, because he makes intercession for the saints according to God."},{"v":28,"t":"We know that all things work together for good for those who love God, for those who are called according to his purpose."},{"v":29,"t":"For whom he foreknew, he also predestined to be conformed to the image of his Son, that he might be the firstborn among many brothers."},{"v":30,"t":"Whom he predestined, those he also called. Whom he called, those he also justified. Whom he justified, those he also glorified."},{"v":31,"t":"What then shall we say about these things? If God is for us, who can be against us?"},{"v":32,"t":"He who didn’t spare his own Son, but delivered him up for us all, how would he not also with him freely give us all things?"},{"v":33,"t":"Who could bring a charge against God’s chosen ones? It is God who justifies."},{"v":34,"t":"Who is he who condemns? It is Christ who died, yes rather, who was raised from the dead, who is at the right hand of God, who also makes intercession for us."},{"v":35,"t":"Who shall separate us from the love of Christ? Could oppression, or anguish, or persecution, or famine, or nakedness, or peril, or sword?"},{"v":36,"t":"Even as it is written, “For your sake we are killed all day long. We were accounted as sheep for the slaughter.”"},{"v":37,"t":"No, in all these things we are more than conquerors through him who loved us."},{"v":38,"t":"For I am persuaded that neither death, nor life, nor angels, nor principalities, nor things present, nor things to come, nor powers,"},{"v":39,"t":"nor height, nor depth, nor any other created thing will be able to separate us from God’s love which is in Christ Jesus our Lord."}],"hr":[{"v":1,"t":"Nikakve dakle sada osude onima koji su u Kristu Isusu!"},{"v":2,"t":"Ta zakon Duha života u Kristu Isusu oslobodi me zakona grijeha i smrti."},{"v":3,"t":"Uistinu, što je bilo nemoguće Zakonu, jer je zbog tijela onemoćao, Bog je učinio: poslavši Sina svoga u obličju grešnoga tijela i s obzirom na grijeh, osudi grijeh u tijelu"},{"v":4,"t":"da se pravednost Zakona ispuni u nama koji ne živimo po tijelu nego po Duhu."},{"v":5,"t":"Da, oni koji žive po tijelu, teže za onim što je tjelesno; a koji po Duhu, za onim što je Duhovo:"},{"v":6,"t":"težnja je tijela smrt, a težnja Duha život i mir."},{"v":7,"t":"Jer težnja je tijela protivna Bogu: zakonu se Božjemu ne podvrgava, a i ne može."},{"v":8,"t":"Oni pak koji su u tijelu, ne mogu se Bogu svidjeti."},{"v":9,"t":"A vi niste u tijelu, nego u Duhu, ako Duh Božji prebiva u vama. A nema li tko Duha Kristova, taj nije njegov."},{"v":10,"t":"I ako je Krist u vama, tijelo je doduše mrtvo zbog grijeha, ali Duh je život zbog pravednosti."},{"v":11,"t":"Ako li Duh Onoga koji uskrisi Isusa od mrtvih prebiva u vama, Onaj koji uskrisi Krista od mrtvih oživit će i smrtna tijela vaša po Duhu svome koji prebiva u vama."},{"v":12,"t":"Dakle, braćo, dužnici smo, ali ne tijelu da po tijelu živimo!"},{"v":13,"t":"Jer ako po tijelu živite, umrijeti vam je, ako li pak Duhom usmrćujete tjelesna djela, živjet ćete."},{"v":14,"t":"Svi koje vodi Duh Božji sinovi su Božji."},{"v":15,"t":"Ta ne primiste duh robovanja da se opet bojite, nego primiste Duha posinstva u kojem kličemo: “Abba! Oče!”"},{"v":16,"t":"Sam Duh susvjedok je s našim duhom da smo djeca Božja;"},{"v":17,"t":"ako pak djeca, onda i baštinici, baštinici Božji, a subaštinici Kristovi, kada doista s njime zajedno trpimo, da se zajedno s njime i proslavimo."},{"v":18,"t":"Smatram, uistinu: sve patnje sadašnjega vremena nisu ništa prema budućoj slavi koja se ima očitovati u nama."},{"v":19,"t":"Doista, stvorenje sa svom žudnjom iščekuje ovo objavljenje sinova Božjih:"},{"v":20,"t":"stvorenje je uistinu podvrgnuto ispraznosti - ne po svojoj volji, nego zbog onoga koji ga podvrgnu - ali u nadi."},{"v":21,"t":"Jer i stvorenje će se osloboditi robovanja pokvarljivosti da sudjeluje u slobodi i slavi djece Božje."},{"v":22,"t":"Jer znamo: sve stvorenje zajedno uzdiše i muči se u porođajnim bolima sve do sada."},{"v":23,"t":"Ali ne samo ono! I mi koji imamo prvine Duha, i mi u sebi uzdišemo iščekujući posinstvo, otkupljenje svoga tijela."},{"v":24,"t":"Ta u nadi smo spašeni! Nada pak koja se vidi nije nada. Jer što tko gleda, kako da se tomu i nada?"},{"v":25,"t":"Nadamo li se pak onomu čega ne gledamo, postojano to iščekujemo."},{"v":26,"t":"Tako i Duh potpomaže našu nemoć. Doista ne znamo što da molimo kako valja, ali se sam Duh za nas zauzima neizrecivim uzdasima."},{"v":27,"t":"A Onaj koji proniče srca zna koja je želja Duha - da se on po Božju zauzima za svete."},{"v":28,"t":"Znamo pak da Bog u svemu na dobro surađuje s onima koji ga ljube, s onima koji su odlukom njegovom pozvani."},{"v":29,"t":"Jer koje predvidje, te i predodredi da budu suobličeni slici Sina njegova te da on bude prvorođenac među mnogom braćom."},{"v":30,"t":"Koje pak predodredi, te i pozva; koje pozva, te i opravda; koje opravda, te i proslavi."},{"v":31,"t":"Što ćemo dakle na to reći? Ako je Bog za nas, tko će protiv nas?"},{"v":32,"t":"Ta on ni svojega Sina nije poštedio, nego ga je za sve nas predao! Kako nam onda s njime neće sve darovati?"},{"v":33,"t":"Tko će optužiti izabranike Božje? Bog opravdava!"},{"v":34,"t":"Tko će osuditi? Krist Isus umrije, štoviše i uskrsnu, on je i zdesna Bogu - on se baš zauzima za nas!"},{"v":35,"t":"Tko će nas rastaviti od ljubavi Kristove? Nevolja? Tjeskoba? Progonstvo? Glad? Golotinja? Pogibao? Mač?"},{"v":36,"t":"Kao što je pisano: Poradi tebe ubijaju nas dan za danom i mi smo im ko ovce za klanje."},{"v":37,"t":"U svemu tome nadmoćno pobjeđujemo po onome koji nas uzljubi."},{"v":38,"t":"Uvjeren sam doista: ni smrt ni život, ni anđeli ni vlasti, ni sadašnjost ni budućnost, ni sile,"},{"v":39,"t":"ni dubina ni visina, ni ikoji drugi stvor neće nas moći rastaviti od ljubavi Božje u Kristu Isusu Gospodinu našem."}]},"9":{"fa":[{"v":1,"t":"در مسیح راست می‌گویم و دروغ نی و ضمیر من در روح‌القدس مرا شاهد است،"},{"v":2,"t":"که مرا غمی عظیم و در دلم وجع دائمی است."},{"v":3,"t":"زیرا راضی هم می‌بودم که خود از مسیح محروم شوم در راه برادرانم که بحسب جسم خویشان منند،"},{"v":4,"t":"که ایشان اسرائیلی‌اند و پسرخواندگی وجلال و عهدها و امانت شریعت و عبادت ووعده‌ها از آن ایشان است؛"},{"v":5,"t":"که پدران از آن ایشانند و از ایشان مسیح بحسب جسم شد که فوق از همه است، خدای متبارک تا ابدالاباد، آمین."},{"v":6,"t":"ولکن چنین نیست که کلام خدا ساقط شده باشد؛ زیرا همه که از اسرائیل‌اند، اسرائیلی نیستند،"},{"v":7,"t":"و نه نسل ابراهیم تمام فرزند هستند؛ بلکه نسل تو در اسحاق خوانده خواهند شد."},{"v":8,"t":"یعنی فرزندان جسم، فرزندان خدا نیستند، بلکه فرزندان وعده از نسل محسوب می‌شوند."},{"v":9,"t":"زیراکلام وعده این است که موافق چنین وقت خواهم آمد و ساره را پسری خواهد بود."},{"v":10,"t":"و نه این فقط، بلکه رفقه نیز چون از یک شخص یعنی از پدر مااسحاق حامله شد،"},{"v":11,"t":"زیرا هنگامی که هنوز تولدنیافته بودند و عملی نیک یا بد نکرده، تا اراده خدابرحسب اختیار ثابت شود نه از اعمال بلکه ازدعوت کننده"},{"v":12,"t":"بدو گفته شد که «بزرگتر کوچکتر را بندگی خواهد نمود.»"},{"v":13,"t":"چنانکه مکتوب است: «یعقوب را دوست داشتم اما عیسو را دشمن.»"},{"v":14,"t":"پس چه گوییم؟ آیا نزد خدا بی‌انصافی است؟ حاشا!"},{"v":15,"t":"زیرا به موسی می‌گوید: «رحم خواهم فرمود بر هر‌که رحم کنم و رافت خواهم نمود بر هر‌که رافت نمایم.»"},{"v":16,"t":"لاجرم نه ازخواهش کننده و نه از شتابنده است، بلکه ازخدای رحم کننده."},{"v":17,"t":"زیرا کتاب به فرعون می‌گوید: «برای همین تو را برانگیختم تا قوت خود را در تو ظاهر سازم و تا نام من در تمام جهان ندا شود.»"},{"v":18,"t":"بنابراین هر‌که را می‌خواهد رحم می‌کند و هر‌که را می‌خواهد سنگدل می‌سازد."},{"v":19,"t":"پس مرا می‌گویی: «دیگر چرا ملامت می‌کند؟ زیرا کیست که با اراده او مقاومت نموده باشد؟»"},{"v":20,"t":"نی بلکه تو کیستی‌ای انسان که با خدا معارضه می‌کنی؟ آیا مصنوع به صانع می‌گوید که چرا مراچنین ساختی؟"},{"v":21,"t":"یا کوزه‌گر اختیار بر گل نداردکه از یک خمیره ظرفی عزیز و ظرفی ذلیل بسازد؟"},{"v":22,"t":"و اگر خدا چون اراده نمود که غضب خود را ظاهر سازد و قدرت خویش را بشناساند، ظروف غضب را که برای هلاکت آماده‌شده بود، به حلم بسیار متحمل گردید،"},{"v":23,"t":"و تا دولت جلال خود را بشناساند بر ظروف رحمتی که آنها را ازقبل برای جلال مستعد نمود،"},{"v":24,"t":"و آنها را نیزدعوت فرمود یعنی ما نه از یهود فقط بلکه ازامت‌ها نیز."},{"v":25,"t":"چنانکه در هوشع هم می‌گوید: «آنانی را که قوم من نبودند، قوم خود خواهم خواند و او را که دوست نداشتم محبوبه خود."},{"v":26,"t":"و جایی که به ایشان گفته شد که شما قوم من نیستید، در آنجا پسران خدای حی خوانده خواهند شد.»"},{"v":27,"t":"و اشعیا نیز در حق اسرائیل ندامی کند که «هرچند عدد بنی‌اسرائیل مانند ریگ دریا باشد، لکن بقیه نجات خواهند یافت؛"},{"v":28,"t":"زیراخداوند کلام خود را تمام و منقطع ساخته، برزمین به عمل خواهد آورد.»"},{"v":29,"t":"و چنانکه اشعیاپیش اخبار نمود که «اگر رب الجنود برای ما نسلی نمی گذارد، هرآینه مثل سدوم می‌شدیم و مانندغموره می‌گشتیم.»"},{"v":30,"t":"پس چه گوییم؟ امت هایی که در‌پی عدالت نرفتند، عدالت را حاصل نمودند، یعنی عدالتی که از ایمان است."},{"v":31,"t":"لکن اسرائیل که در‌پی شریعت عدالت می‌رفتند، به شریعت عدالت نرسیدند."},{"v":32,"t":"از چه سبب؟ از این جهت که نه از راه ایمان بلکه از راه اعمال شریعت آن را طلبیدند، زیرا که به سنگ مصادم لغزش خوردند."},{"v":33,"t":"چنانکه مکتوب است که «اینک در صهیون سنگی مصادم و صخره لغزش می‌نهم و هر‌که براو ایمان آورد، خجل نخواهد گردید.»"}],"en":[{"v":1,"t":"I tell the truth in Christ. I am not lying, my conscience testifying with me in the Holy Spirit"},{"v":2,"t":"that I have great sorrow and unceasing pain in my heart."},{"v":3,"t":"For I could wish that I myself were accursed from Christ for my brothers’ sake, my relatives according to the flesh"},{"v":4,"t":"who are Israelites; whose is the adoption, the glory, the covenants, the giving of the law, the service, and the promises;"},{"v":5,"t":"of whom are the fathers, and from whom is Christ as concerning the flesh, who is over all, God, blessed forever. Amen."},{"v":6,"t":"But it is not as though the word of God has come to nothing. For they are not all Israel that are of Israel."},{"v":7,"t":"Neither, because they are Abraham’s offspring, are they all children. But, “your offspring will be accounted as from Isaac.”"},{"v":8,"t":"That is, it is not the children of the flesh who are children of God, but the children of the promise are counted as heirs."},{"v":9,"t":"For this is a word of promise: “At the appointed time I will come, and Sarah will have a son.”"},{"v":10,"t":"Not only so, but Rebekah also conceived by one, by our father Isaac."},{"v":11,"t":"For being not yet born, neither having done anything good or bad, that the purpose of God according to election might stand, not of works, but of him who calls,"},{"v":12,"t":"it was said to her, “The elder will serve the younger.”"},{"v":13,"t":"Even as it is written, “Jacob I loved, but Esau I hated.”"},{"v":14,"t":"What shall we say then? Is there unrighteousness with God? May it never be!"},{"v":15,"t":"For he said to Moses, “I will have mercy on whom I have mercy, and I will have compassion on whom I have compassion.”"},{"v":16,"t":"So then it is not of him who wills, nor of him who runs, but of God who has mercy."},{"v":17,"t":"For the Scripture says to Pharaoh, “For this very purpose I caused you to be raised up, that I might show in you my power, and that my name might be proclaimed in all the earth.”"},{"v":18,"t":"So then, he has mercy on whom he desires, and he hardens whom he desires."},{"v":19,"t":"You will say then to me, “Why does he still find fault? For who withstands his will?”"},{"v":20,"t":"But indeed, O man, who are you to reply against God? Will the thing formed ask him who formed it, “Why did you make me like this?”"},{"v":21,"t":"Or hasn’t the potter a right over the clay, from the same lump to make one part a vessel for honor, and another for dishonor?"},{"v":22,"t":"What if God, willing to show his wrath and to make his power known, endured with much patience vessels of wrath prepared for destruction,"},{"v":23,"t":"and that he might make known the riches of his glory on vessels of mercy, which he prepared beforehand for glory—"},{"v":24,"t":"us, whom he also called, not from the Jews only, but also from the Gentiles?"},{"v":25,"t":"As he says also in Hosea, “I will call them ‘my people,’ which were not my people; and her ‘beloved,’ who was not beloved.”"},{"v":26,"t":"“It will be that in the place where it was said to them, ‘You are not my people,’ there they will be called ‘children of the living God.’”"},{"v":27,"t":"Isaiah cries concerning Israel, “If the number of the children of Israel are as the sand of the sea, it is the remnant who will be saved;"},{"v":28,"t":"for he will finish the work and cut it short in righteousness, because the Lord will make a short work upon the earth.”"},{"v":29,"t":"As Isaiah has said before, “Unless the Lord of Armies had left us a seed, we would have become like Sodom, and would have been made like Gomorrah.”"},{"v":30,"t":"What shall we say then? That the Gentiles, who didn’t follow after righteousness, attained to righteousness, even the righteousness which is of faith;"},{"v":31,"t":"but Israel, following after a law of righteousness, didn’t arrive at the law of righteousness."},{"v":32,"t":"Why? Because they didn’t seek it by faith, but as it were by works of the law. They stumbled over the stumbling stone,"},{"v":33,"t":"even as it is written, “Behold, I lay in Zion a stumbling stone and a rock of offense; and no one who believes in him will be disappointed.”"}],"hr":[{"v":1,"t":"Istinu govorim u Kristu, ne lažem; susvjedok mi je savjest moja u Duhu Svetom:"},{"v":2,"t":"silna mi je tuga i neprekidna bol u srcu."},{"v":3,"t":"Da, htio bih ja sam proklet biti, odvojen od Krista, za braću svoju, sunarodnjake svoje po tijelu."},{"v":4,"t":"Oni su Izraelci, njihovo je posinstvo, i Slava, i Savezi, i zakonodavstvo, i bogoštovlje, i obećanja;"},{"v":5,"t":"njihovi su i oci, od njih je, po tijelu, i Krist, koji je iznad svega, Bog blagoslovljen u vjekove. Amen."},{"v":6,"t":"Ali ne kao da se izjalovila riječ Božja. Jer nisu Izrael svi koji potječu od Izraela;"},{"v":7,"t":"i nisu svi djeca Abrahamova zato što su njegovo potomstvo, nego po Izaku će ti se nazivati potomstvo;"},{"v":8,"t":"to jest: djeca tijela nisu i djeca Božja, nego - djeca obećanja računaju se u potomstvo."},{"v":9,"t":"Evo doista riječi obećanja: U ovo ću doba doći i Sara će imati sina."},{"v":10,"t":"Ali ne samo to! I Rebeka je s jednim, s Izakom, ocem našim, zanijela."},{"v":11,"t":"Pa kad još blizanci ne bijahu rođeni niti učiniše što dobro ili zlo - da bi trajnom ostala odluka Božja o izabranju:"},{"v":12,"t":"ne po djelima, nego po onome tko poziva - rečeno joj je: Stariji će služiti mlađemu,"},{"v":13,"t":"kako je pisano: Jakova sam zavolio, a Ezav mi omrznu."},{"v":14,"t":"Što ćemo dakle reći? Možda da u Boga ima nepravde? Nipošto!"},{"v":15,"t":"Ta Mojsiju veli: Smilovat ću se komu hoću da se smilujem; sažalit ću se nad kim hoću da se sažalim."},{"v":16,"t":"Nije dakle do onoga koji hoće ni do onoga koji trči, nego do Boga koji se smiluje."},{"v":17,"t":"Jer Pismo veli faraonu: Zato te upravo podigoh da na tebi pokažem svoju moć i da se razglasi ime moje po svoj zemlji."},{"v":18,"t":"Tako dakle: smiluje se komu hoće, a otvrdnjuje koga hoće."},{"v":19,"t":"Da, reći ćeš mi: Što se onda još tuži? Ta tko se to volji njegovoj odupro?"},{"v":20,"t":"Čovječe, tko si ti zapravo da se pravdaš s Bogom? Zar da djelo rekne tvorcu: “Što si me ovakvim načinio?”"},{"v":21,"t":"Ili zar lončar nema vlasti nad glinom da od istoga tijesta načini posudu sad časnu, sad nečasnu."},{"v":22,"t":"A što ako je Bog, hoteći očitovati gnjev i obznaniti svoju moć u silnoj strpljivosti podnosio posude gnjeva, dozrele za propast,"},{"v":23,"t":"da obznani bogatstvo slave svoje na posudama milosrđa, koje unaprijed pripravi za slavu,"},{"v":24,"t":"na nama koje pozva ne samo između Židova nego i između pogana?"},{"v":25,"t":"Tako i u Hošeji veli: Ne-narod moj prozvat ću narodom mojim i Neljubljenu ljubljenom."},{"v":26,"t":"Na mjestu gdje im je rečeno: Vi niste moj narod prozvat će se sinovi Boga živoga."},{"v":27,"t":"Izaija pak proglasuje o Izraelu: Zaista, sinova će Izraelovih brojem biti kao pijeska morskog - Ostatak će se spasiti;"},{"v":28,"t":"jer riječ će ispuniti i uskoro izvršiti Gospodin na zemlji."},{"v":29,"t":"Tako je Izaija i prorekao: Da nam Gospodin nad Vojskama ne ostavi sjeme, ko Sodoma bismo bili i Gomori nalik."},{"v":30,"t":"Što ćemo dakle reći? Da pogani koji nisu tražili pravednosti stekoše pravednost, pravednost po vjeri."},{"v":31,"t":"Izrael pak koji je tražio neki zakon pravednosti, nije do zakona dopro."},{"v":32,"t":"Zašto? Jer nije tražio po vjeri, nego kao po djelima. Spotakoše se o kamen spoticanja,"},{"v":33,"t":"kao što je pisano: Evo postavljam na Sionu kamen spoticanja i stijenu posrtanja. Ali tko u nj vjeruje, neće se postidjeti."}]},"10":{"fa":[{"v":1,"t":"ای برادران خوشی دل من و دعای من نزد خدا بجهت اسرائیل برای نجات ایشان است."},{"v":2,"t":"زیرا بجهت ایشان شهادت می‌دهم که برای خدا غیرت دارند لکن نه از روی معرفت."},{"v":3,"t":"زیرا که چون عدالت خدا را نشناخته، می‌خواستند عدالت خود را ثابت کنند، مطیع عدالت خدا نگشتند."},{"v":4,"t":"زیرا که مسیح است انجام شریعت بجهت عدالت برای هر کس که ایمان آورد."},{"v":5,"t":"زیرا موسی عدالت شریعت را بیان می‌کندکه «هر‌که به این عمل کند، در این خواهدزیست.»"},{"v":6,"t":"لکن عدالت ایمان بدینطور سخن می‌گوید که «در خاطر خود مگو کیست که به آسمان صعود کند یعنی تا مسیح را فرود آورد،"},{"v":7,"t":"یا کیست که به هاویه نزول کند یعنی تا مسیح رااز مردگان برآورد.»"},{"v":8,"t":"لکن چه می‌گوید؟ اینکه «کلام نزد تو و در دهانت و در قلب تو است یعنی‌این کلام ایمان که به آن وعظ می‌کنیم.»"},{"v":9,"t":"زیرا اگربه زبان خود عیسی خداوند را اعتراف کنی و دردل خود ایمان آوری که خدا او را از مردگان برخیزانید، نجات خواهی یافت."},{"v":10,"t":"چونکه به دل ایمان آورده می‌شود برای عدالت و به زبان اعتراف می‌شود بجهت نجات."},{"v":11,"t":"و کتاب می‌گوید «هر‌که به او ایمان آورد خجل نخواهدشد.»"},{"v":12,"t":"زیرا که در یهود و یونانی تفاوتی نیست که همان خداوند، خداوند همه است و دولتمنداست برای همه که نام او را می‌خوانند."},{"v":13,"t":"زیرا هرکه نام خداوند را بخواند نجات خواهد یافت."},{"v":14,"t":"پس چگونه بخوانند کسی را که به او ایمان نیاورده‌اند؟ و چگونه ایمان آورند به کسی‌که خبراو را نشنیده‌اند؟ و چگونه بشنوند بدون واعظ؟"},{"v":15,"t":"و چگونه وعظ کنند جز اینکه فرستاده شوند؟ چنانکه مکتوب است که «چه زیبا است پایهای آنانی که به سلامتی بشارت می‌دهند و به چیزهای نیکو مژده می‌دهند.»"},{"v":16,"t":"لکن همه بشارت را گوش نگرفتند زیرا اشعیا می‌گوید «خداوندا کیست که اخبار ما را باور کرد؟»"},{"v":17,"t":"لهذا ایمان از شنیدن است و شنیدن از کلام خدا."},{"v":18,"t":"لکن می‌گویم آیانشنیدند؟ البته شنیدند: «صوت ایشان در تمام جهان منتشر گردید و کلام ایشان تا اقصای ربع مسکون رسید.»"},{"v":19,"t":"و می‌گویم آیا اسرائیل ندانسته‌اند؟ اول موسی می‌گوید: «من شما را به غیرت می‌آورم به آن که امتی نیست و بر قوم بی‌فهم شما را خشمگین خواهم ساخت.»"},{"v":20,"t":"واشعیا نیز جرات کرده، می‌گوید: آنانی که طالب من نبودند مرا یافتند و به کسانی که مرا نطلبیدندظاهر گردیدم.»"},{"v":21,"t":"اما در حق اسرائیل می‌گوید: «تمام روز دستهای خود را دراز کردم به سوی قومی نامطیع و مخالف.»"}],"en":[{"v":1,"t":"Brothers, my heart’s desire and my prayer to God is for Israel, that they may be saved."},{"v":2,"t":"For I testify about them that they have a zeal for God, but not according to knowledge."},{"v":3,"t":"For being ignorant of God’s righteousness, and seeking to establish their own righteousness, they didn’t subject themselves to the righteousness of God."},{"v":4,"t":"For Christ is the fulfillment of the law for righteousness to everyone who believes."},{"v":5,"t":"For Moses writes about the righteousness of the law, “The one who does them will live by them.”"},{"v":6,"t":"But the righteousness which is of faith says this, “Don’t say in your heart, ‘Who will ascend into heaven?’ (that is, to bring Christ down);"},{"v":7,"t":"or, ‘Who will descend into the abyss?’ (that is, to bring Christ up from the dead.)”"},{"v":8,"t":"But what does it say? “The word is near you, in your mouth and in your heart;” that is, the word of faith which we preach:"},{"v":9,"t":"that if you will confess with your mouth that Jesus is Lord and believe in your heart that God raised him from the dead, you will be saved."},{"v":10,"t":"For with the heart one believes resulting in righteousness; and with the mouth confession is made resulting in salvation."},{"v":11,"t":"For the Scripture says, “Whoever believes in him will not be disappointed.”"},{"v":12,"t":"For there is no distinction between Jew and Greek; for the same Lord is Lord of all, and is rich to all who call on him."},{"v":13,"t":"For, “Whoever will call on the name of the Lord will be saved.”"},{"v":14,"t":"How then will they call on him in whom they have not believed? How will they believe in him whom they have not heard? How will they hear without a preacher?"},{"v":15,"t":"And how will they preach unless they are sent? As it is written: “How beautiful are the feet of those who preach the Good News of peace, who bring glad tidings of good things!”"},{"v":16,"t":"But they didn’t all listen to the glad news. For Isaiah says, “Lord, who has believed our report?”"},{"v":17,"t":"So faith comes by hearing, and hearing by the word of God."},{"v":18,"t":"But I say, didn’t they hear? Yes, most certainly, “Their sound went out into all the earth, their words to the ends of the world.”"},{"v":19,"t":"But I ask, didn’t Israel know? First Moses says, “I will provoke you to jealousy with that which is no nation. I will make you angry with a nation void of understanding.”"},{"v":20,"t":"Isaiah is very bold and says, “I was found by those who didn’t seek me. I was revealed to those who didn’t ask for me.”"},{"v":21,"t":"But about Israel he says, “All day long I stretched out my hands to a disobedient and contrary people.”"}],"hr":[{"v":1,"t":"Braćo! Želja je srca moga i molitva Bogu za njih: da se spase."},{"v":2,"t":"Svjedočim doista za njih: imaju revnosti Božje, ali ne u pravom razumijevanju."},{"v":3,"t":"Ne priznajući, doista, Božje pravednosti i tražeći uspostaviti svoju, pravednosti se Božjoj ne podložiše."},{"v":4,"t":"Jer dovršetak je Zakona Krist - na opravdanje svakomu tko vjeruje."},{"v":5,"t":"Da, Mojsije piše o onoj pravednosti iz Zakona: Tko je vrši, naći će život u njoj."},{"v":6,"t":"A pravednost iz vjere ovako veli: Nemoj reći u srcu svom: Tko će se popeti na nebo - to jest Krista svesti?"},{"v":7,"t":"Ili: Tko će sići u bezdan - to jest izvesti Krista od mrtvih?"},{"v":8,"t":"Nego što veli? Blizu ti je Riječ, u ustima tvojim i u srcu tvome - to jest Riječ vjere koju propovijedamo."},{"v":9,"t":"Jer ako ustima ispovijedaš da je Isus Gospodin, i srcem vjeruješ da ga je Bog uskrisio od mrtvih, bit ćeš spašen."},{"v":10,"t":"Doista, srcem vjerovati opravdava, a ustima ispovijedati spasava."},{"v":11,"t":"Jer veli Pismo: Tko god u nj vjeruje, neće se postidjeti."},{"v":12,"t":"Nema uistinu razlike između Židova i Grka jer jedan je Gospodin sviju, bogat prema svima koji ga prizivlju."},{"v":13,"t":"Jer: Tko god prizove ime Gospodnje, bit će spašen."},{"v":14,"t":"Ali kako da prizovu onoga u koga ne povjerovaše? A kako da povjeruju u onoga koga nisu čuli? Kako pak da čuju bez propovjednika?"},{"v":15,"t":"A kako propovijedati bez poslanja? Tako je pisano: Kako li su ljupke noge onih koji donose blagovijest dobra."},{"v":16,"t":"Ali nisu svi poslušali blagovijesti - evanđelja! Zaista, Izaija veli: Gospodine, tko povjerova našoj poruci?"},{"v":17,"t":"Dakle: vjera po poruci, a poruka riječju Kristovom."},{"v":18,"t":"Nego pitam: Zar nisu čuli? Dapače! Po svoj zemlji razliježe se jeka, riječi njihove sve do nakraj svijeta."},{"v":19,"t":"Onda pitam: Zar Izrael nije shvatio? Najprije Mojsije veli: Ja ću vas na ljubomor izazvati pukom ništavnim, razdražit ću vas glupim nekim narodom."},{"v":20,"t":"Izaija pak hrabro veli: Nađoše me koji me ne tražahu, objavih se onima koji me ne pitahu."},{"v":21,"t":"A Izraelu veli: Cio dan pružah ruku narodu nepokornom i buntovnom."}]},"11":{"fa":[{"v":1,"t":"پس می‌گویم آیا خدا قوم خود را ردکرد؟ حاشا! زیرا که من نیز اسرائیلی ازاولاد ابراهیم از سبط بنیامین هستم."},{"v":2,"t":"خدا قوم خود را که از قبل شناخته بود، رد نفرموده است. آیا نمی دانید که کتاب در الیاس چه می‌گوید، چگونه بر اسرائیل از خدا استغاثه می‌کند"},{"v":3,"t":"که «خداوندا انبیای تو را کشته و مذبحهای تو راکنده‌اند و من به تنهایی مانده‌ام و در قصد جان من نیز می‌باشند»؟"},{"v":4,"t":"لکن وحی بدو چه می‌گوید؟ اینکه «هفت هزار مرد بجهت خود نگاه داشتم که به نزد بعل زانو نزده‌اند»."},{"v":5,"t":"پس همچنین در زمان حاضر نیز بقیتی بحسب اختیار فیض مانده است."},{"v":6,"t":"و اگر از راه فیض است دیگر از اعمال نیست وگرنه فیض دیگر فیض نیست. اما اگر از اعمال است دیگر از فیض نیست والا عمل دیگر عمل نیست."},{"v":7,"t":"پس مقصود چیست؟ اینکه اسرائیل آنچه راکه می‌طلبد نیافته است، لکن برگزیدگان یافتند وباقی ماندگان سختدل گردیدند؛"},{"v":8,"t":"چنانکه مکتوب است که «خدا بدیشان روح خواب‌آلود دادچشمانی که نبیند و گوشهایی که نشنود تا امروز.»"},{"v":9,"t":"و داود می‌گوید که «مائده ایشان برای ایشان تله و دام و سنگ مصادم و عقوبت باد؛"},{"v":10,"t":"چشمان ایشان تار شود تا نبینند و پشت ایشان را دائم خم گردان.»"},{"v":11,"t":"پس می‌گویم آیا لغزش خوردند تا بیفتند؟ حاشا! بلکه از لغزش ایشان نجات به امت‌ها رسیدتا در ایشان غیرت پدید آورد."},{"v":12,"t":"پس چون لغزش ایشان دولتمندی جهان گردید و نقصان ایشان دولتمندی امت‌ها، به چند مرتبه زیادترپری ایشان خواهد بود."},{"v":13,"t":"زیرا به شما‌ای امت هاسخن می‌گویم پس از این‌روی که رسول امت هامی باشم خدمت خود را تمجید می‌نمایم،"},{"v":14,"t":"تاشاید ابنای جنس خود را به غیرت آورم و بعضی از ایشان را برهانم."},{"v":15,"t":"زیرا اگر رد شدن ایشان مصالحت عالم شد، باز‌یافتن ایشان چه خواهدشد؟ جز حیات از مردگان!"},{"v":16,"t":"و چون نوبر مقدس است، همچنان خمیره و هرگاه ریشه مقدس است، همچنان شاخه‌ها."},{"v":17,"t":"و چون بعضی از شاخه‌ها بریده شدند و تو که زیتون بری بودی در آنها پیوند گشتی و در ریشه وچربی زیتون شریک شدی،"},{"v":18,"t":"بر شاخه‌ها فخرمکن و اگر فخر کنی تو حامل ریشه نیستی بلکه ریشه حامل تو است."},{"v":19,"t":"پس می‌گویی که «شاخه‌ها بریده شدند تا من پیوند شوم؟»"},{"v":20,"t":"آفرین بجهت بی‌ایمانی بریده شدند و تومحض ایمان پایدار هستی. مغرور مباش بلکه بترس!"},{"v":21,"t":"زیرا اگر خدا بر شاخه های طبیعی شفقت نفرمود، بر تو نیز شفقت نخواهد کرد."},{"v":22,"t":"پس مهربانی و سختی خدا را ملاحظه نما؛ اماسختی بر آنانی که افتادند، اما مهربانی برتو اگر درمهربانی ثابت باشی والا تو نیز بریده خواهی شد."},{"v":23,"t":"و اگر ایشان نیز در بی‌ایمانی نمانند باز پیوندخواهند شد، زیرا خدا قادر است که ایشان را باردیگر بپیوندد."},{"v":24,"t":"زیرا اگر تو از زیتون طبیعی بری بریده شده، برخلاف طبع به زیتون نیکو پیوندگشتی، به چند مرتبه زیادتر آنانی که طبیعی‌اند درزیتون خویش پیوند خواهند شد."},{"v":25,"t":"زیرا‌ای برادران نمی خواهم شما از این سربی خبر باشید که مبادا خود را دانا انگارید که مادامی که پری امت‌ها درنیاید، سختدلی بربعضی از اسرائیل طاری گشته است."},{"v":26,"t":"وهمچنین همگی اسرائیل نجات خواهند یافت، چنانکه مکتوب است که «از صهیون نجات‌دهنده‌ای ظاهر خواهد شد و بی‌دینی را ازیعقوب خواهد برداشت؛"},{"v":27,"t":"و این است عهد من باایشان در زمانی که گناهانشان را بردارم.»"},{"v":28,"t":"نظر به انجیل بجهت شما دشمنان‌اند، لکن نظر به اختیاربه‌خاطر اجداد محبوبند."},{"v":29,"t":"زیرا که در نعمتهاودعوت خدا بازگشتن نیست."},{"v":30,"t":"زیرا همچنان‌که شما در سابق مطیع خدا نبودید و الان به‌سبب نافرمانی‌ایشان رحمت یافتید،"},{"v":31,"t":"همچنین ایشان نیز الان نافرمان شدند تا بجهت رحمتی که بر شما است بر ایشان نیز رحم شود"},{"v":32,"t":"زیرا خدا همه رادر نافرمانی بسته است تا بر همه رحم فرماید."},{"v":33,"t":"زهی عمق دولتمندی و حکمت و علم خدا! چقدر بعید از غوررسی است احکام او وفوق از کاوش است طریقهای وی!"},{"v":34,"t":"زیرا کیست که رای خداوند را دانسته باشد؟ یا که مشیر اوشده؟"},{"v":35,"t":"یا که سبقت جسته چیزی بدو داده تا به او باز داده شود؟"},{"v":36,"t":"زیرا که از او و به او و تا او همه‌چیز است؛ و او را تا ابدالاباد جلال باد، آمین."}],"en":[{"v":1,"t":"I ask then, did God reject his people? May it never be! For I also am an Israelite, a descendant of Abraham, of the tribe of Benjamin."},{"v":2,"t":"God didn’t reject his people, whom he foreknew. Or don’t you know what the Scripture says about Elijah? How he pleads with God against Israel:"},{"v":3,"t":"“Lord, they have killed your prophets. They have broken down your altars. I am left alone, and they seek my life.”"},{"v":4,"t":"But how does God answer him? “I have reserved for myself seven thousand men who have not bowed the knee to Baal.”"},{"v":5,"t":"Even so too at this present time also there is a remnant according to the election of grace."},{"v":6,"t":"And if by grace, then it is no longer of works; otherwise grace is no longer grace. But if it is of works, it is no longer grace; otherwise work is no longer work."},{"v":7,"t":"What then? That which Israel seeks for, that he didn’t obtain, but the chosen ones obtained it, and the rest were hardened."},{"v":8,"t":"According as it is written, “God gave them a spirit of stupor, eyes that they should not see, and ears that they should not hear, to this very day.”"},{"v":9,"t":"David says, “Let their table be made a snare, a trap, a stumbling block, and a retribution to them."},{"v":10,"t":"Let their eyes be darkened, that they may not see. Always keep their backs bent.”"},{"v":11,"t":"I ask then, did they stumble that they might fall? May it never be! But by their fall salvation has come to the Gentiles, to provoke them to jealousy."},{"v":12,"t":"Now if their fall is the riches of the world, and their loss the riches of the Gentiles, how much more their fullness!"},{"v":13,"t":"For I speak to you who are Gentiles. Since then as I am an apostle to Gentiles, I glorify my ministry,"},{"v":14,"t":"if by any means I may provoke to jealousy those who are my flesh, and may save some of them."},{"v":15,"t":"For if the rejection of them is the reconciling of the world, what would their acceptance be, but life from the dead?"},{"v":16,"t":"If the first fruit is holy, so is the lump. If the root is holy, so are the branches."},{"v":17,"t":"But if some of the branches were broken off, and you, being a wild olive, were grafted in among them and became partaker with them of the root and of the richness of the olive tree,"},{"v":18,"t":"don’t boast over the branches. But if you boast, remember that it is not you who support the root, but the root supports you."},{"v":19,"t":"You will say then, “Branches were broken off, that I might be grafted in.”"},{"v":20,"t":"True; by their unbelief they were broken off, and you stand by your faith. Don’t be conceited, but fear;"},{"v":21,"t":"for if God didn’t spare the natural branches, neither will he spare you."},{"v":22,"t":"See then the goodness and severity of God. Toward those who fell, severity; but toward you, goodness, if you continue in his goodness; otherwise you also will be cut off."},{"v":23,"t":"They also, if they don’t continue in their unbelief, will be grafted in, for God is able to graft them in again."},{"v":24,"t":"For if you were cut out of that which is by nature a wild olive tree, and were grafted contrary to nature into a good olive tree, how much more will these, which are the natural branches, be grafted into their own olive tree?"},{"v":25,"t":"For I don’t desire you to be ignorant, brothers, of this mystery, so that you won’t be wise in your own conceits, that a partial hardening has happened to Israel, until the fullness of the Gentiles has come in,"},{"v":26,"t":"and so all Israel will be saved. Even as it is written, “There will come out of Zion the Deliverer, and he will turn away ungodliness from Jacob."},{"v":27,"t":"This is my covenant with them, when I will take away their sins.”"},{"v":28,"t":"Concerning the Good News, they are enemies for your sake. But concerning the election, they are beloved for the fathers’ sake."},{"v":29,"t":"For the gifts and the calling of God are irrevocable."},{"v":30,"t":"For as you in time past were disobedient to God, but now have obtained mercy by their disobedience,"},{"v":31,"t":"even so these also have now been disobedient, that by the mercy shown to you they may also obtain mercy."},{"v":32,"t":"For God has bound all to disobedience, that he might have mercy on all."},{"v":33,"t":"Oh the depth of the riches both of the wisdom and the knowledge of God! How unsearchable are his judgments, and his ways past tracing out!"},{"v":34,"t":"“For who has known the mind of the Lord? Or who has been his counselor?”"},{"v":35,"t":"“Or who has first given to him, and it will be repaid to him again?”"},{"v":36,"t":"For of him and through him and to him are all things. To him be the glory for ever! Amen."}],"hr":[{"v":1,"t":"Pitam dakle: Zar je Bog odbacio narod svoj? Nipošto? Ta i ja sam Izraelac, iz potomstva Abrahamova, plemena Benjaminova."},{"v":2,"t":"Nije Bog odbacio naroda svojega koga predvidje. Ili zar ne znate što veli Pismo, ono o Iliji - kako se tuži Bogu na Izraela:"},{"v":3,"t":"Gospode, proroke tvoje pobiše, žrtvenike tvoje porušiše; ja ostadoh sam i još mi o glavi rade."},{"v":4,"t":"Pa što mu veli Božji glas? Ostavih sebi sedam tisuća ljudi koji ne prignuše koljena pred Baalom."},{"v":5,"t":"Tako dakle i u sadašnje vrijeme postoji Ostatak po milosnom izboru."},{"v":6,"t":"Ako pak po milosti, nije po djelima; inače milost nije više milost!"},{"v":7,"t":"Što dakle? Što Izrael ište, to nije postigao, ali izabrani postigoše. Ostali pak otvrdnuše,"},{"v":8,"t":"kao što je pisano: Dade im Bog duh obamrlosti, oči da ne vide, uši da ne čuju sve do dana današnjega."},{"v":9,"t":"I David veli: Nek im stol pred njima bude zamkom, i mrežom, i stupicom, i plaćom."},{"v":10,"t":"Nek im potamne oči da ne vide i leđa im zauvijek pogni!"},{"v":11,"t":"Pitam dakle: jesu li posrnuli da propadnu? Nipošto! Naprotiv: po njihovu posrtaju spasenje poganima da se tako oni, Židovi, izazovu na ljubomor."},{"v":12,"t":"Pa ako je njihov posrtaj bogatstvo za svijet, i njihovo smanjenje bogatstvo za pogane, koliko li će više to biti njihov puni broj?"},{"v":13,"t":"Vama pak, poganima, velim: ja kao apostol pogana službu svoju proslavljam"},{"v":14,"t":"ne bih li na ljubomor izazvao njih, tijelo svoje, i spasio neke od njih."},{"v":15,"t":"Jer ako je njihovo odbačenje izmirenje svijeta, što li će biti njihovo prihvaćanje ako ne oživljenje od mrtvih?"},{"v":16,"t":"Ako li su prvine svete, sveto je i tijesto; ako li je korijen svet, svete su i grane."},{"v":17,"t":"Pa ako su neke grane odlomljene, a ti, divlja maslina, pricijepljen umjesto njih, postao suzajedničar korijena, sočnosti masline,"},{"v":18,"t":"ne uznosi se nad grane. Ako li se hoćeš uznositi - ne nosiš ti korijena, nego korijen tebe."},{"v":19,"t":"Reći ćeš na to: grane su odlomljene da se ja pricijepim."},{"v":20,"t":"Dobro! Oni su zbog nevjere odlomljeni, a ti po vjeri stojiš. Ne uznosi se, nego strahuj!"},{"v":21,"t":"Jer ako Bog ne poštedje prirodnih grana, ni tebe neće poštedjeti."},{"v":22,"t":"Promotri dakle dobrotu i strogost Božju: strogost na palima, a dobrotu Božju na sebi ako ostaneš u toj dobroti, inače ćeš i ti biti odsječen."},{"v":23,"t":"A i oni, ako ne ostanu u nevjeri, bit će pricijepljeni; ta moćan je Bog da ih opet pricijepi."},{"v":24,"t":"Doista, ako si ti, po naravi divlja maslina, odsječen pa mimo narav pricijepljen na pitomu maslinu, koliko li će lakše oni po naravi biti pricijepljeni na vlastitu maslinu!"},{"v":25,"t":"Jer ne bih htio, braćo, da budete sami po sebi pametni, a da ne znate ovo otajstvo: djelomično je otvrdnuće zadesilo Izraela dok punina pogana ne uđe."},{"v":26,"t":"I tako će se cio Izrael spasiti, kako je pisano: Doći će sa Siona Otkupitelj, odvratit će bezbožnost od Jakova."},{"v":27,"t":"I to će biti moj Savez s njima, kad uklonim grijehe njihove."},{"v":28,"t":"U pogledu evanđelja oni su, istina, protivnici poradi vas, ali u pogledu izabranja oni su ljubimci poradi otaca."},{"v":29,"t":"Ta neopozivi su dari i poziv Božji!"},{"v":30,"t":"Doista, kao što vi nekoć bijaste neposlušni Bogu, a sada po njihovoj neposlušnosti zadobiste milosrđe"},{"v":31,"t":"tako i oni sada po milosrđu vama iskazanu postadoše neposlušni da i oni sada zadobiju milosrđe."},{"v":32,"t":"Jer Bog je sve zatvorio u neposlušnost da se svima smiluje."},{"v":33,"t":"O dubino bogatstva, i mudrosti, i spoznanja Božjega! Kako li su nedokučivi sudovi i neistraživi putovi njegovi!"},{"v":34,"t":"Doista, tko spozna misao Gospodnju, tko li mu bi savjetnikom?"},{"v":35,"t":"Ili: tko ga darom preteče da bi mu se uzvratiti moralo?"},{"v":36,"t":"Jer sve je od njega i po njemu i za njega! Njemu slava u vjekove! Amen."}]},"12":{"fa":[{"v":1,"t":"زندگی مسیحی لهذا‌ای برادران شما را به رحمتهای خدا استدعا می‌کنم که بدنهای خود راقربانی زنده مقدس پسندیده خدا بگذرانید که عبادت معقول شما است."},{"v":2,"t":"و همشکل این جهان مشوید بلکه به تازگی ذهن خود صورت خود راتبدیل دهید تا شما دریافت کنید که اراده نیکوی پسندیده کامل خدا چیست."},{"v":3,"t":"زیرا به آن فیضی که به من عطا شده است، هریکی از شما را می‌گویم که فکرهای بلندتر ازآنچه شایسته است مکنید بلکه به اعتدال فکرنمایید، به اندازه آن بهره ایمان که خدا به هر کس قسمت فرموده است."},{"v":4,"t":"زیرا همچنان‌که در یک بدن اعضای بسیار داریم و هر عضوی را یک کارنیست،"},{"v":5,"t":"همچنین ما که بسیاریم، یک جسدهستیم در مسیح، اما فرد اعضای یکدیگر."},{"v":6,"t":"پس چون نعمتهای مختلف داریم بحسب فیضی که به ما داده شد، خواه نبوت برحسب موافقت ایمان،"},{"v":7,"t":"یا خدمت در خدمت گذاری، یا معلم در تعلیم،"},{"v":8,"t":"یا واعظ در موعظه، یا بخشنده به سخاوت، یاپیشوا به اجتهاد، یا رحم کننده به‌سرور."},{"v":9,"t":"محبت بی‌ریا باشد. از بدی نفرت کنید و به نیکویی بپیوندید."},{"v":10,"t":"با محبت برادرانه یکدیگر رادوست دارید و هر یک دیگری را بیشتر از خوداکرام بنماید."},{"v":11,"t":"در اجتهاد کاهلی نورزید و درروح سرگرم شده، خداوند را خدمت نمایید."},{"v":12,"t":"در امید مسرور و در مصیبت صابر و در دعامواظب باشید."},{"v":13,"t":"مشارکت در احتیاجات مقدسین کنید و در مهمانداری ساعی باشید."},{"v":14,"t":"برکت بطلبید بر آنانی که بر شما جفا کنند؛ برکت بطلبید و لعن مکنید."},{"v":15,"t":"خوشی کنید باخوشحالان و ماتم نمایید با ماتمیان."},{"v":16,"t":"برای یکدیگر همان فکر داشته باشید و در چیزهای بلند فکر مکنید بلکه با ذلیلان مدارا نمایید و خودرا دانا مشمارید."},{"v":17,"t":"هیچ‌کس را به عوض بدی بدی مرسانید. پیش جمیع مردم تدارک کارهای نیکو بینید."},{"v":18,"t":"اگر ممکن است بقدر قوه خود باجمیع خلق به صلح بکوشید."},{"v":19,"t":"‌ای محبوبان انتقام خود را مکشید بلکه خشم را مهلت دهید، زیرا مکتوب است «خداوند می‌گوید که انتقام ازآن من است من جزا خواهم داد.»"},{"v":20,"t":"پس «اگردشمن تو گرسنه باشد، او را سیر کن و اگر تشنه است، سیرابش نما زیرا اگر چنین کنی اخگرهای آتش بر سرش خواهی انباشت.»"},{"v":21,"t":"مغلوب بدی مشو بلکه بدی را به نیکویی مغلوب ساز."}],"en":[{"v":1,"t":"Therefore I urge you, brothers, by the mercies of God, to present your bodies a living sacrifice, holy, acceptable to God, which is your spiritual service."},{"v":2,"t":"Don’t be conformed to this world, but be transformed by the renewing of your mind, so that you may prove what is the good, well-pleasing, and perfect will of God."},{"v":3,"t":"For I say through the grace that was given me, to everyone who is among you, not to think of yourself more highly than you ought to think; but to think reasonably, as God has apportioned to each person a measure of faith."},{"v":4,"t":"For even as we have many members in one body, and all the members don’t have the same function,"},{"v":5,"t":"so we, who are many, are one body in Christ, and individually members of one another,"},{"v":6,"t":"having gifts differing according to the grace that was given to us: if prophecy, let’s prophesy according to the proportion of our faith;"},{"v":7,"t":"or service, let’s give ourselves to service; or he who teaches, to his teaching;"},{"v":8,"t":"or he who exhorts, to his exhorting; he who gives, let him do it with generosity; he who rules, with diligence; he who shows mercy, with cheerfulness."},{"v":9,"t":"Let love be without hypocrisy. Abhor that which is evil. Cling to that which is good."},{"v":10,"t":"In love of the brothers be tenderly affectionate to one another; in honor prefer one another,"},{"v":11,"t":"not lagging in diligence, fervent in spirit, serving the Lord,"},{"v":12,"t":"rejoicing in hope, enduring in troubles, continuing steadfastly in prayer,"},{"v":13,"t":"contributing to the needs of the saints, and given to hospitality."},{"v":14,"t":"Bless those who persecute you; bless, and don’t curse."},{"v":15,"t":"Rejoice with those who rejoice. Weep with those who weep."},{"v":16,"t":"Be of the same mind one toward another. Don’t set your mind on high things, but associate with the humble. Don’t be wise in your own conceits."},{"v":17,"t":"Repay no one evil for evil. Respect what is honorable in the sight of all men."},{"v":18,"t":"If it is possible, as much as it is up to you, be at peace with all men."},{"v":19,"t":"Don’t seek revenge yourselves, beloved, but give place to God’s wrath. For it is written, “Vengeance belongs to me; I will repay, says the Lord.”"},{"v":20,"t":"Therefore “If your enemy is hungry, feed him. If he is thirsty, give him a drink; for in doing so, you will heap coals of fire on his head.”"},{"v":21,"t":"Don’t be overcome by evil, but overcome evil with good."}],"hr":[{"v":1,"t":"Zaklinjem vas, braćo, milosrđem Božjim: prikažite svoja tijela za žrtvu živu, svetu, Bogu milu - kao svoje duhovno bogoslužje."},{"v":2,"t":"Ne suobličujte se ovomu svijetu, nego se preobrazujte obnavljanjem svoje pameti da mognete razabirati što je volja Božja, što li je dobro, Bogu milo, savršeno."},{"v":3,"t":"Da, po milosti koja mi je dana svakomu između vas velim: ne precjenjujte se više no što se treba cijeniti, nego cijenite se razumno, kako je već komu Bog odmjerio mjeru vjere."},{"v":4,"t":"Jer kao što u jednom tijelu imamo mnogo udova, a nemaju svi isto djelovanje,"},{"v":5,"t":"tako smo i mi, mnogi, jedno tijelo u Kristu, a pojedinci udovi jedan drugomu."},{"v":6,"t":"Dare pak imamo različite po milosti koja nam je dana: je li to prorokovanje - neka je primjereno vjeri;"},{"v":7,"t":"je li služenje - neka je u služenju; je li poučavanje - u poučavanju;"},{"v":8,"t":"je li hrabrenje - u hrabrenju; tko dijeli, neka je darežljiv; tko je predstojnik - revan; tko iskazuje milosrđe - radostan!"},{"v":9,"t":"Ljubav nehinjena! Zazirite oda zla, prianjajte uz dobro!"},{"v":10,"t":"Srdačno se ljubite pravim bratoljubljem! Pretječite jedni druge poštovanjem!"},{"v":11,"t":"U revnosti budite hitri, u duhu gorljivi, Gospodinu služite!"},{"v":12,"t":"U nadi budite radosni, u nevolji strpljivi, u molitvi postojani!"},{"v":13,"t":"Pritječite u pomoć svetima u nuždi, gajite gostoljubivost!"},{"v":14,"t":"Blagoslivljajte svoje progonitelje, blagoslivljajte, a ne proklinjite!"},{"v":15,"t":"Radujte se s radosnima, plačite sa zaplakanima!"},{"v":16,"t":"Budite istomišljenici među sobom! Neka vas ne zanosi što je visoko, nego privlači što je ponizno. Ne umišljajte si da ste mudri!"},{"v":17,"t":"Nikome zlo za zlo ne vraćajte; zauzimajte se za dobro pred svim ljudima!"},{"v":18,"t":"Ako je moguće, koliko je do vas, u miru budite sa svim ljudima!"},{"v":19,"t":"Ne osvećujte se, ljubljeni, nego dajte mjesta Božjem gnjevu. Ta pisano je: Moja je odmazda, ja ću je vratiti, veli Gospodin."},{"v":20,"t":"Naprotiv: Ako je gladan neprijatelj tvoj, nahrani ga, i ako je žedan, napoj ga! Činiš li tako, ugljevlje mu ražareno zgrćeš na glavu."},{"v":21,"t":"Ne daj se pobijediti zlom, nego dobrim svladavaj zlo."}]},"13":{"fa":[{"v":1,"t":"هر شخص مطیع قدرتهای برتر بشود، زیرا که قدرتی جز از خدا نیست و آنهایی که هست از جانب خدا مرتب شده است."},{"v":2,"t":"حتی هر‌که با قدرت مقاومت نماید، مقاومت باترتیب خدا نموده باشد و هر‌که مقاومت کند، حکم بر خود آورد."},{"v":3,"t":"زیرا از حکام عمل نیکو راخوفی نیست بلکه عمل بد را. پس اگر می‌خواهی که از آن قدرت ترسان نشوی، نیکویی کن که از اوتحسین خواهی یافت."},{"v":4,"t":"زیرا خادم خداست برای تو به نیکویی؛ لکن هرگاه بدی کنی، بترس چونکه شمشیر را عبث برنمی دارد، زیرا او خادم خداست و با غضب انتقام از بدکاران می‌کشد."},{"v":5,"t":"لهذا لازم است که مطیع او شوی نه به‌سبب غضب فقط بلکه به‌سبب ضمیر خود نیز."},{"v":6,"t":"زیرا که به این سبب باج نیز می‌دهید، چونکه خدام خدا ومواظب در همین امر هستند."},{"v":7,"t":"پس حق هرکس رابه او ادا کنید: باج را به مستحق باج و جزیه را به مستحق جزیه و ترس را به مستحق ترس و عزت را به مستحق عزت."},{"v":8,"t":"مدیون احدی به چیزی مشوید جز به محبت نمودن با یکدیگر، زیرا کسی‌که دیگری رامحبت نماید شریعت را به‌جا آورده باشد."},{"v":9,"t":"زیراکه زنا مکن، قتل مکن، دزدی مکن، شهادت دروغ مده، طمع مورز و هر حکمی دیگر که هست، همه شامل است در این کلام که همسایه خود راچون خود محبت نما."},{"v":10,"t":"محبت به همسایه خودبدی نمی کند پس محبت تکمیل شریعت است."},{"v":11,"t":"و خصوص چون وقت را می‌دانید که الحال ساعت رسیده است که ما را باید از خواب بیدارشویم زیرا که الان نجات ما نزدیک تر است از آن وقتی که ایمان آوردیم."},{"v":12,"t":"شب منقضی شد و روز نزدیک آمد. پس اعمال تاریکی را بیرون کرده، اسلحه نور را بپوشیم."},{"v":13,"t":"و با شایستگی رفتار کنیم چنانکه در روز، نه در بزمها و سکرها وفسق و فجور و نزاع و حسد؛"},{"v":14,"t":"بلکه عیسی مسیح خداوند را بپوشید و برای شهوات جسمانی تدارک نبینید."}],"en":[{"v":1,"t":"Let every soul be in subjection to the higher authorities, for there is no authority except from God, and those who exist are ordained by God."},{"v":2,"t":"Therefore he who resists the authority withstands the ordinance of God; and those who withstand will receive to themselves judgment."},{"v":3,"t":"For rulers are not a terror to the good work, but to the evil. Do you desire to have no fear of the authority? Do that which is good, and you will have praise from the authority,"},{"v":4,"t":"for he is a servant of God to you for good. But if you do that which is evil, be afraid, for he doesn’t bear the sword in vain; for he is a servant of God, an avenger for wrath to him who does evil."},{"v":5,"t":"Therefore you need to be in subjection, not only because of the wrath, but also for conscience’ sake."},{"v":6,"t":"For this reason you also pay taxes, for they are servants of God’s service, continually doing this very thing."},{"v":7,"t":"Therefore give everyone what you owe: if you owe taxes, pay taxes; if customs, then customs; if respect, then respect; if honor, then honor."},{"v":8,"t":"Owe no one anything, except to love one another; for he who loves his neighbor has fulfilled the law."},{"v":9,"t":"For the commandments, “You shall not commit adultery,” “You shall not murder,” “You shall not steal,” “You shall not covet,” and whatever other commandments there are, are all summed up in this saying, namely, “You shall love your neighbor as yourself.”"},{"v":10,"t":"Love doesn’t harm a neighbor. Love therefore is the fulfillment of the law."},{"v":11,"t":"Do this, knowing the time, that it is already time for you to awaken out of sleep, for salvation is now nearer to us than when we first believed."},{"v":12,"t":"The night is far gone, and the day is near. Let’s therefore throw off the deeds of darkness, and let’s put on the armor of light."},{"v":13,"t":"Let’s walk properly, as in the day; not in reveling and drunkenness, not in sexual promiscuity and lustful acts, and not in strife and jealousy."},{"v":14,"t":"But put on the Lord Jesus Christ, and make no provision for the flesh, for its lusts."}],"hr":[{"v":1,"t":"Svaka duša neka se podlaže vlastima nad sobom. Jer nema vlasti doli od Boga: koje postoje, od Boga su postavljene."},{"v":2,"t":"Stoga tko se suprotstavlja vlasti, Božjoj se odredbi protivi; koji se pak protive, sami će na se navući osudu."},{"v":3,"t":"Vladari doista nisu strah i trepet zbog dobra, nego zbog zla djela. Hoćeš li se ne bojati vlasti? Dobro čini pa ćeš imati pohvalu od nje!"},{"v":4,"t":"Ta Božji je ona poslužitelj - tebi na dobro. Ako li zlo činiš, strahuj! Ne nosi uzalud mača! Božji je ona poslužitelj: gnjev njegov iskaljuje na onome koji zlo čini."},{"v":5,"t":"Treba se stoga podlagati, ne samo zbog gnjeva nego i zbog savjesti."},{"v":6,"t":"Zato i poreze plaćate: ta službenici su Božji oni koji se time bave."},{"v":7,"t":"Dajte svakomu što mu pripada: komu porez - porez, komu carina - carina, komu poštovanje - poštovanje, komu čast - čast."},{"v":8,"t":"Nikomu ništa ne dugujte, osim da jedni druge ljubite. Jer tko drugoga ljubi, ispunio je Zakon."},{"v":9,"t":"Uistinu: Ne čini preljuba! Ne ubij! Ne ukradi! Ne poželi! i ima li koja druga zapovijed, sažeta je u ovoj riječi: Ljubi svoga bližnjega kao sebe samoga."},{"v":10,"t":"Ljubav bližnjemu zla ne čini. Punina dakle Zakona jest ljubav."},{"v":11,"t":"To tim više što shvaćate ovaj čas: vrijeme je već da se oda sna prenemo jer nam je sada spasenje bliže nego kad povjerovasmo."},{"v":12,"t":"Noć poodmače, dan se približi! Odložimo dakle djela tame i zaodjenimo se oružjem svjetlosti."},{"v":13,"t":"Kao po danu pristojno hodimo, ne u pijankama i pijančevanjima, ne u priležništvima i razvratnostima, ne u svađi i ljubomoru,"},{"v":14,"t":"nego zaodjenite se Gospodinom Isusom Kristom i, u brizi za tijelo, ne pogodujte požudama."}]},"14":{"fa":[{"v":1,"t":"و کسی را که در ایمان ضعیف باشدبپذیرید، لکن نه برای محاجه درمباحثات."},{"v":2,"t":"یکی ایمان دارد که همه‌چیز را بایدخورد اما آنکه ضعیف است بقول می‌خورد."},{"v":3,"t":"پس خورنده ناخورنده را حقیر نشمارد وناخورنده بر خورنده حکم نکند زیرا خدا او راپذیرفته است."},{"v":4,"t":"تو کیستی که بر بنده کسی دیگرحکم می‌کنی؟ او نزد آقای خود ثابت یا ساقطمی شود. لیکن استوار خواهد شد زیرا خدا قادراست که او را ثابت نماید."},{"v":5,"t":"یکی یک روز را از دیگری بهتر می‌داند ودیگری هر روز را برابر می‌شمارد. پس هر کس درذهن خود متیقن بشود."},{"v":6,"t":"آنکه روز را عزیز می‌داندبخاطر خداوند عزیزش می‌دارد و آنکه روز راعزیز نمی دارد هم برای خداوند نمی دارد؛ و هرکه می‌خورد برای خداوند می‌خورد زیرا خدا راشکر می‌گوید، و آنکه نمی خورد برای خداوندنمی خورد و خدا را شکر می‌گوید."},{"v":7,"t":"زیرا احدی از ما به خود زیست نمی کند و هیچ‌کس به خودنمی میرد."},{"v":8,"t":"زیرا اگر زیست کنیم برای خداوندزیست می‌کنیم و اگر بمیریم برای خداوند می میریم. پس خواه زنده باشیم، خواه بمیریم، ازآن خداوندیم."},{"v":9,"t":"زیرا برای همین مسیح مرد وزنده گشت تا بر زندگان و مردگان سلطنت کند."},{"v":10,"t":"لکن تو چرا بر برادر خود حکم می‌کنی؟ یا تونیز چرا برادر خود را حقیر می‌شماری؟ زانرو که همه پیش مسند مسیح حاضر خواهیم شد."},{"v":11,"t":"زیرا مکتوب است «خداوند می‌گوید به حیات خودم قسم که هر زانویی نزد من خم خواهد شد وهر زبانی به خدا اقرار خواهد نمود.»"},{"v":12,"t":"پس هریکی از ما حساب خود را به خدا خواهد داد."},{"v":13,"t":"بنابراین بر یکدیگر حکم نکنیم بلکه حکم کنید به اینکه کسی سنگی مصادم یا لغزشی در راه برادر خود ننهد."},{"v":14,"t":"می‌دانم و در عیسی خداوندیقین می‌دارم که هیچ‌چیز در ذات خود نجس نیست جز برای آن کسی‌که آن را نجس پندارد؛ برای او نجس است."},{"v":15,"t":"زیرا هرگاه برادرت به خوراک آزرده شود، دیگر به محبت رفتارنمی کنی. به خوراک خود هلاک مساز کسی را که مسیح در راه او بمرد."},{"v":16,"t":"پس مگذارید که نیکویی شما را بد گویند."},{"v":17,"t":"زیرا ملکوت خدا اکل وشرب نیست بلکه عدالت و سلامتی و خوشی درروح‌القدس."},{"v":18,"t":"زیرا هر‌که در این امور خدمت مسیح را کند، پسندیده خدا و مقبول مردم است."},{"v":19,"t":"پس آن اموری را که منشا سلامتی و بنای یکدیگر است پیروی نمایید."},{"v":20,"t":"بجهت خوراک کار خدا را خراب مساز. البته همه‌چیز پاک است، لیکن بد است برای آن شخص که برای لغزش می‌خورد."},{"v":21,"t":"گوشت نخوردن و شراب ننوشیدن و کاری نکردن که باعث ایذا یا لغزش یا ضعف برادرت باشد نیکواست."},{"v":22,"t":"آیا تو ایمان داری؟ پس برای خودت درحضور خدا آن را بدار، زیرا خوشابحال کسی‌که بر خود حکم نکند در آنچه نیکو می‌شمارد."},{"v":23,"t":"لکن آنکه شک دارد اگر بخورد ملزم می‌شود، زیرا به ایمان نمی خورد؛ و هر‌چه از ایمان نیست گناه است."}],"en":[{"v":1,"t":"Now accept one who is weak in faith, but not for disputes over opinions."},{"v":2,"t":"One man has faith to eat all things, but he who is weak eats only vegetables."},{"v":3,"t":"Don’t let him who eats despise him who doesn’t eat. Don’t let him who doesn’t eat judge him who eats, for God has accepted him."},{"v":4,"t":"Who are you who judge another’s servant? To his own lord he stands or falls. Yes, he will be made to stand, for God has power to make him stand."},{"v":5,"t":"One man esteems one day as more important. Another esteems every day alike. Let each man be fully assured in his own mind."},{"v":6,"t":"He who observes the day, observes it to the Lord; and he who does not observe the day, to the Lord he does not observe it. He who eats, eats to the Lord, for he gives God thanks. He who doesn’t eat, to the Lord he doesn’t eat, and gives God thanks."},{"v":7,"t":"For none of us lives to himself, and none dies to himself."},{"v":8,"t":"For if we live, we live to the Lord. Or if we die, we die to the Lord. If therefore we live or die, we are the Lord’s."},{"v":9,"t":"For to this end Christ died, rose, and lived again, that he might be Lord of both the dead and the living."},{"v":10,"t":"But you, why do you judge your brother? Or you again, why do you despise your brother? For we will all stand before the judgment seat of Christ."},{"v":11,"t":"For it is written, “‘As I live,’ says the Lord, ‘to me every knee will bow. Every tongue will confess to God.’”"},{"v":12,"t":"So then each one of us will give account of himself to God."},{"v":13,"t":"Therefore let’s not judge one another any more, but judge this rather, that no man put a stumbling block in his brother’s way, or an occasion for falling."},{"v":14,"t":"I know and am persuaded in the Lord Jesus that nothing is unclean of itself; except that to him who considers anything to be unclean, to him it is unclean."},{"v":15,"t":"Yet if because of food your brother is grieved, you walk no longer in love. Don’t destroy with your food him for whom Christ died."},{"v":16,"t":"Then don’t let your good be slandered,"},{"v":17,"t":"for God’s Kingdom is not eating and drinking, but righteousness, peace, and joy in the Holy Spirit."},{"v":18,"t":"For he who serves Christ in these things is acceptable to God and approved by men."},{"v":19,"t":"So then, let’s follow after things which make for peace, and things by which we may build one another up."},{"v":20,"t":"Don’t overthrow God’s work for food’s sake. All things indeed are clean, however it is evil for that man who creates a stumbling block by eating."},{"v":21,"t":"It is good to not eat meat, drink wine, nor do anything by which your brother stumbles, is offended, or is made weak."},{"v":22,"t":"Do you have faith? Have it to yourself before God. Happy is he who doesn’t judge himself in that which he approves."},{"v":23,"t":"But he who doubts is condemned if he eats, because it isn’t of faith; and whatever is not of faith is sin."}],"hr":[{"v":1,"t":"Slaboga u vjeri prigrlite, ali ne da se prepirete o mišljenjima."},{"v":2,"t":"Netko vjeruje da smije sve jesti, slabi opet jede samo povrće."},{"v":3,"t":"Tko jede, neka ne prezire onoga tko ne jede; tko pak ne jede, neka ne sudi onoga tko jede. Ta Bog ga je prigrlio."},{"v":4,"t":"Tko si ti da sudiš tuđega slugu? Svojemu Gospodaru i stoji i pada! A stajat će jer moćan je Gospodin da ga podrži."},{"v":5,"t":"Netko razlikuje dan od dana, nekomu je opet svaki dan jednak. Samo nek je svatko posve uvjeren u svoje mišljenje."},{"v":6,"t":"Tko na dan misli, poradi Gospodina misli; i tko jede, poradi Gospodina jede: zahvaljuje Bogu. I tko ne jede, poradi Gospodina ne jede i - zahvaljuje Bogu."},{"v":7,"t":"Jer nitko od nas sebi ne živi, nitko sebi ne umire."},{"v":8,"t":"Doista, ako živimo, Gospodinu živimo, i ako umiremo, Gospodinu umiremo. Živimo li dakle ili umiremo - Gospodinovi smo."},{"v":9,"t":"Ta Krist zato umrije i oživje da gospodar bude i mrtvima i živima."},{"v":10,"t":"A ti, što sudiš brata svoga? Ili ti, što prezireš brata svoga? Ta svi ćemo stati pred sudište Božje."},{"v":11,"t":"Jer pisano je: Života mi moga, govori Gospodin, prignut će se preda mnom svako koljeno i svaki će jezik priznati Boga."},{"v":12,"t":"Svaki će dakle od nas za sebe Bogu dati račun."},{"v":13,"t":"Dakle, ne sudimo više jedan drugoga, nego radije sudite o tome da ne valja postavljati bratu stupice ili spoticala."},{"v":14,"t":"Znam i uvjeren sam u Gospodinu: ništa samo od sebe nije nečisto. Samo je onomu nečisto tko to smatra nečistim."},{"v":15,"t":"Doista, ako je poradi hrane tvoj brat ražalošćen, već nisi na putu ljubavi. Ne upropašćuj tom svojom hranom onoga za koga je Krist umro!"},{"v":16,"t":"Nemojte da se pogrđuje vaše dobro!"},{"v":17,"t":"Ta kraljevstvo Božje nije jelo ili piće, nego pravednost, mir i radost u Duhu Svetome."},{"v":18,"t":"Da, tko tako Kristu služi, mio je Bogu i cijene ga ljudi."},{"v":19,"t":"Nastojmo stoga promicati mir i uzajamno izgrađivanje!"},{"v":20,"t":"Ne razaraj djela Božjega poradi hrane! Sve je, istina, čisto, ali je zlo za onoga tko na sablazan jede."},{"v":21,"t":"Dobro je ne jesti mesa i ne piti vina i ne uzimati ništa o što se tvoj brat spotiče."},{"v":22,"t":"Ti imaš uvjerenje. Za sebe ga imaj pred Bogom. Blago onomu tko samoga sebe ne osuđuje u onom na što se odlučuje!"},{"v":23,"t":"Jede li tko dvoumeći, osudio se jer ne radi iz uvjerenja. A sve što nije iz uvjerenja, grijeh je."}]},"15":{"fa":[{"v":1,"t":"و ما که توانا هستیم، ضعفهای ناتوانان رامتحمل بشویم و خوشی خود را طالب نباشیم."},{"v":2,"t":"هر یکی از ما همسایه خود را خوش بسازد در آنچه برای بنا نیکو است."},{"v":3,"t":"زیرا مسیح نیز خوشی خود را طالب نمی بود، بلکه چنانکه مکتوب است «ملامتهای ملامت کنندگان تو برمن طاری گردید.»"},{"v":4,"t":"زیرا همه‌چیزهایی که از قبل مکتوب شد، برای تعلیم ما نوشته شد تا به صبر وتسلی کتاب امیدوار باشیم."},{"v":5,"t":"الان خدای صبر و تسلی شما را فیض عطاکناد تا موافق مسیح عیسی با یکدیگر یکرای باشید."},{"v":6,"t":"تا یکدل و یکزبان شده، خدا و پدرخداوند ما عیسی مسیح را تمجید نمایید."},{"v":7,"t":"پس یکدیگر را بپذیرید، چنانکه مسیح نیز مارا پذیرفت برای جلال خدا."},{"v":8,"t":"زیرا می‌گویم عیسی مسیح خادم ختنه گردید بجهت راستی خدا تا وعده های اجداد را ثابت گرداند،"},{"v":9,"t":"و تاامت‌ها خدا را تمجید نمایند به‌سبب رحمت اوچنانکه مکتوب است که «از این جهت تو را درمیان امت‌ها اقرار خواهم کرد و به نام تو تسبیح خواهم خواند.»"},{"v":10,"t":"و نیز می‌گوید «ای امت‌ها باقوم او شادمان شوید.»"},{"v":11,"t":"و ایض «ای جمیع امت‌ها خداوند را حمد گویید و‌ای تمامی قومهااو را مدح نمایید.»"},{"v":12,"t":"و اشعیا نیز می‌گوید که «ریشه یسا خواهد بود و آنکه برای حکمرانی امت‌ها مبعوث شود، امید امت‌ها بر وی خواهدبود.»"},{"v":13,"t":"الان خدای امید، شما را از کمال خوشی وسلامتی در ایمان پر سازد تا به قوت روح‌القدس در امید افزوده گردید."},{"v":14,"t":"لکن‌ای برادران من، خود نیز درباره شمایقین می‌دانم که خود از نیکویی مملو و پر از کمال معرفت و قادر بر نصیحت نمودن یکدیگر هستید."},{"v":15,"t":"لیکن‌ای برادران بسیار جسارت ورزیده، من خود نیز به شما جزئی نوشتم تا شما را یادآوری نمایم به‌سبب آن فیضی که خدا به من بخشیده است،"},{"v":16,"t":"تا خادم عیسی مسیح شوم برای امت هاو کهانت انجیل خدا را به‌جا آورم تا هدیه امت هامقبول افتد، مقدس شده به روح‌القدس."},{"v":17,"t":"پس به مسیح عیسی در کارهای خدا فخر دارم."},{"v":18,"t":"زیراجرات نمی کنم که سخنی بگویم جز در آن اموری که مسیح بواسطه من به عمل آورد، برای اطاعت امت‌ها در قول و فعل،"},{"v":19,"t":"به قوت آیات ومعجزات و به قوت روح خدا. بحدی که ازاورشلیم دور زده تا به الیرکون بشارت مسیح راتکمیل نمودم."},{"v":20,"t":"اما حریص بودم که بشارت چنان بدهم، نه در جایی که اسم مسیح شهرت یافته بود، مبادا بر بنیاد غیری بنا نمایم."},{"v":21,"t":"بلکه چنانکه مکتوب است «آنانی که خبر او را نیافتند، خواهند دید و کسانی که نشنیدند، خواهندفهمید.»"},{"v":22,"t":"بنابراین‌بارها از آمدن نزد شما ممنوع شدم."},{"v":23,"t":"لکن چون الان مرا در این ممالک دیگرجایی نیست و سالهای بسیار است که مشتاق آمدن نزد شما بوده‌ام،"},{"v":24,"t":"هرگاه به اسپانیا سفرکنم، به نزد شما خواهم آمد زیرا امیدوار هستم که شما را در عبور ملاقات کنم و شما مرا به آن سوی مشایعت نمایید، بعد از آنکه از ملاقات شما اندکی سیر شوم."},{"v":25,"t":"لکن الان عازم اورشلیم هستم تا مقدسین را خدمت کنم."},{"v":26,"t":"زیرا که اهل مکادونیه و اخائیه مصلحت دیدند که زکاتی برای مفلسین مقدسین اورشلیم بفرستند،"},{"v":27,"t":"بدین رضادادند و بدرستی که مدیون ایشان هستند زیرا که چون امت‌ها از روحانیات ایشان بهره‌مندگردیدند، لازم شد که در جسمانیات نیز خدمت ایشان را بکنند."},{"v":28,"t":"پس چون این را انجام دهم واین ثمر را نزد ایشان ختم کنم، از راه شما به اسپانیا خواهم آمد."},{"v":29,"t":"و می‌دانم وقتی که به نزدشما آیم، در کمال برکت انجیل مسیح خواهم آمد."},{"v":30,"t":"لکن‌ای برادران، از شما التماس دارم که بخاطر خداوند ما عیسی مسیح و به محبت روح (القدس )، برای من نزد خدا در دعاها جد وجهدکنید،"},{"v":31,"t":"تا از نافرمانان یهودیه رستگار شوم وخدمت من در اورشلیم مقبول مقدسین افتد،"},{"v":32,"t":"تابرحسب اراده خدا با خوشی نزد شما برسم و باشما استراحت یابم."},{"v":33,"t":"و خدای سلامتی با همه شما باد، آمین."}],"en":[{"v":1,"t":"Now we who are strong ought to bear the weaknesses of the weak, and not to please ourselves."},{"v":2,"t":"Let each one of us please his neighbor for that which is good, to be building him up."},{"v":3,"t":"For even Christ didn’t please himself. But, as it is written, “The reproaches of those who reproached you fell on me.”"},{"v":4,"t":"For whatever things were written before were written for our learning, that through perseverance and through encouragement of the Scriptures we might have hope."},{"v":5,"t":"Now the God of perseverance and of encouragement grant you to be of the same mind with one another according to Christ Jesus,"},{"v":6,"t":"that with one accord you may with one mouth glorify the God and Father of our Lord Jesus Christ."},{"v":7,"t":"Therefore accept one another, even as Christ also accepted you, to the glory of God."},{"v":8,"t":"Now I say that Christ has been made a servant of the circumcision for the truth of God, that he might confirm the promises given to the fathers,"},{"v":9,"t":"and that the Gentiles might glorify God for his mercy. As it is written, “Therefore I will give praise to you among the Gentiles and sing to your name.”"},{"v":10,"t":"Again he says, “Rejoice, you Gentiles, with his people.”"},{"v":11,"t":"Again, “Praise the Lord, all you Gentiles! Let all the peoples praise him.”"},{"v":12,"t":"Again, Isaiah says, “There will be the root of Jesse, he who arises to rule over the Gentiles; in him the Gentiles will hope.”"},{"v":13,"t":"Now may the God of hope fill you with all joy and peace in believing, that you may abound in hope in the power of the Holy Spirit."},{"v":14,"t":"I myself am also persuaded about you, my brothers, that you yourselves are full of goodness, filled with all knowledge, able also to admonish others."},{"v":15,"t":"But I write the more boldly to you in part as reminding you, because of the grace that was given to me by God,"},{"v":16,"t":"that I should be a servant of Christ Jesus to the Gentiles, serving as a priest of the Good News of God, that the offering up of the Gentiles might be made acceptable, sanctified by the Holy Spirit."},{"v":17,"t":"I have therefore my boasting in Christ Jesus in things pertaining to God."},{"v":18,"t":"For I will not dare to speak of any things except those which Christ worked through me for the obedience of the Gentiles, by word and deed,"},{"v":19,"t":"in the power of signs and wonders, in the power of God’s Spirit; so that from Jerusalem and around as far as to Illyricum, I have fully preached the Good News of Christ;"},{"v":20,"t":"yes, making it my aim to preach the Good News, not where Christ was already named, that I might not build on another’s foundation."},{"v":21,"t":"But, as it is written, “They will see, to whom no news of him came. They who haven’t heard will understand.”"},{"v":22,"t":"Therefore also I was hindered these many times from coming to you,"},{"v":23,"t":"but now, no longer having any place in these regions, and having these many years a longing to come to you,"},{"v":24,"t":"whenever I travel to Spain, I will come to you. For I hope to see you on my journey, and to be helped on my way there by you, if first I may enjoy your company for a while."},{"v":25,"t":"But now, I say, I am going to Jerusalem, serving the saints."},{"v":26,"t":"For it has been the good pleasure of Macedonia and Achaia to make a certain contribution for the poor among the saints who are at Jerusalem."},{"v":27,"t":"Yes, it has been their good pleasure, and they are their debtors. For if the Gentiles have been made partakers of their spiritual things, they owe it to them also to serve them in material things."},{"v":28,"t":"When therefore I have accomplished this, and have sealed to them this fruit, I will go on by way of you to Spain."},{"v":29,"t":"I know that when I come to you, I will come in the fullness of the blessing of the Good News of Christ."},{"v":30,"t":"Now I beg you, brothers, by our Lord Jesus Christ and by the love of the Spirit, that you strive together with me in your prayers to God for me,"},{"v":31,"t":"that I may be delivered from those who are disobedient in Judea, and that my service which I have for Jerusalem may be acceptable to the saints,"},{"v":32,"t":"that I may come to you in joy through the will of God, and together with you, find rest."},{"v":33,"t":"Now the God of peace be with you all. Amen."}],"hr":[{"v":1,"t":"Mi jaki treba da nosimo slabosti slabih, a ne da sebi ugađamo."},{"v":2,"t":"Svaki od nas neka ugađa bližnjemu na dobro, na izgrađivanje."},{"v":3,"t":"Ta ni Krist nije sebi ugađao, nego kao što je pisano: Poruge onih koji se rugaju tebi padoše na me."},{"v":4,"t":"Uistinu, što je nekoć napisano, nama je za pouku napisano da po postojanosti i utjesi Pisama imamo nadu."},{"v":5,"t":"A Bog postojanosti i utjehe dao vam da međusobno budete složni po Kristu Isusu"},{"v":6,"t":"te jednodušno, iz jednoga grla, slavite Boga i Oca Gospodina našega Isusa Krista."},{"v":7,"t":"Prigrljujte jedni druge kao što je Krist prigrlio vas na slavu Božju."},{"v":8,"t":"Krist je, velim, postao poslužitelj obrezanika za istinu Božju da ispuni obećanja dana ocima,"},{"v":9,"t":"a pogani da za milosrđe proslave Boga, kao što je pisano: Zato ću te slaviti među pucima i psalam pjevati tvome imenu."},{"v":10,"t":"I još veli: Kličite, puci, s njegovim narodom."},{"v":11,"t":"I još: Hvalite, svi puci, Gospodina, slavili ga svi narodi!"},{"v":12,"t":"Izaija opet veli: Pojavit će se Jišajev izdanak, dignut da vlada narodima, u njemu je nada narodima."},{"v":13,"t":"A Bog nade napunio vas svakom radošću i mirom u vjeri da izobilujete u nadi snagom Duha Svetoga."},{"v":14,"t":"Ja sam, braćo moja, uvjeren: vi ste i sami puni čestitosti, ispunjeni svakim znanjem, sposobni jedni druge urazumljivati."},{"v":15,"t":"Ipak vam djelomično smionije napisah da vas na poznato nekako podsjetim poradi milosti koja mi je dana od Boga -"},{"v":16,"t":"da budem bogoslužnik Krista Isusa među poganima, svećenik evanđelja Božjega te prinos pogana postane ugodan, posvećen Duhom Svetim."},{"v":17,"t":"Imam se dakle čime dičiti u Kristu Isusu s obzirom na ono što je Božje."},{"v":18,"t":"/"},{"v":19,"t":"Jer ne bih se usudio govoriti o nečemu što Krist riječju i djelom, snagom znamenja i čudesa, snagom Duha nije po meni učinio da k poslušnosti privede pogane. Tako sam od Jeruzalema pa uokolo sve do Ilirika pronio evanđelje Kristovo,"},{"v":20,"t":"i to tako da sam se trsio navješćivati evanđelje ne gdje se već spominjao Krist - da ne bih gradio na temeljima drugih -"},{"v":21,"t":"nego, kako je pisano: Vidjet će ga oni kojima nije naviješten, shvatiti oni koji za nj nisu čuli."},{"v":22,"t":"Time sam ponajčešće i bio spriječen doći k vama."},{"v":23,"t":"Sad mi pak više nema mjesta u ovim krajevima, a živa mi je želja, ima već mnogo godina, doći k vama"},{"v":24,"t":"kad pođem u Španjolsku. Nadam se doista da ću vas na proputovanju posjetiti i da ćete me onamo otpraviti pošto mi se najprije bar donekle ispuni želja biti s vama."},{"v":25,"t":"Ali sad idem u Jeruzalem da poslužim svetima."},{"v":26,"t":"Makedonija i Ahaja odlučiše očitovati neko zajedništvo prema siromašnim svetima u Jeruzalemu."},{"v":27,"t":"Da, odlučiše, a i dužnici su im. Jer ako su pogani postali sudionicima njihovih duhovnih dobara, dužni su im u tjelesnima poslužiti."},{"v":28,"t":"Pošto dakle to obavim - ovaj im plod zapečaćen uručim - uputit ću se u Španjolsku i usput k vama."},{"v":29,"t":"A kada dođem k vama, doći ću, znam, s puninom blagoslova Kristova."},{"v":30,"t":"Ali zaklinjem vas, braćo, Gospodinom Isusom Kristom i ljubavlju Duha: suborci mi budite u molitvama Bogu upravljenima za me,"},{"v":31,"t":"da umaknem onim nevjernima u Judeji i da moja pomoć Jeruzalemu bude po volji svetima"},{"v":32,"t":"te s Božjom voljom radosno dođem k vama i s vama zajedno odahnem."},{"v":33,"t":"Bog mira sa svima vama! Amen."}]},"16":{"fa":[{"v":1,"t":"و خواهر ما فیبی را که خادمه کلیسای در کنخریا است، به شما می‌سپارم"},{"v":2,"t":"تااو را در خداوند بطور شایسته مقدسین بپذیرید ودر هر چیزی که به شما محتاج باشد او را اعانت کنید، زیرا که او بسیاری را و خود مرا نیز معاونت می‌نمود."},{"v":3,"t":"سلام برسانید به پرسکلا و اکیلا، همکاران من در مسیح عیسی"},{"v":4,"t":"که در راه جان من گردنهای خود را نهادند و نه من به تنهایی ممنون ایشان هستم، بلکه همه کلیساهای امت‌ها."},{"v":5,"t":"کلیسا را که در خانه ایشان است و حبیب من اپینطس را که برای مسیح نوبر آسیاست سلام رسانید."},{"v":6,"t":"و مریم را که برای شما زحمت بسیار کشید، سلام گویید."},{"v":7,"t":"و اندرونیکوس و یونیاس خویشان مرا که با من اسیر می‌بودند سلام نمایید که مشهور در میان رسولان هستند و قبل از من در مسیح شدند."},{"v":8,"t":"وامپلیاس را که در خداوند حبیب من است، سلام رسانید."},{"v":9,"t":"و اوربانس که با ما در کار مسیح رفیق است و استاخیس حبیب مرا سلام نمایید."},{"v":10,"t":"و اپلیس آزموده شده در مسیح را سلام برسانید و اهل خانه ارستبولس را سلام برسانید."},{"v":11,"t":"و خویش من هیردیون را سلام دهیدو آنانی را از اهل خانه نرگسوس که در خداوندهستند سلام رسانید."},{"v":12,"t":"طریفینا و طریفوسا را که در خداوند زحمت کشیده‌اند سلام گویید؛ وپرسیس محبوبه را که در خداوند زحمت بسیارکشید سلام دهید."},{"v":13,"t":"و روفس برگزیده درخداوند و مادر او و مرا سلام بگویید."},{"v":14,"t":"اسنکریطس را و فلیکون و هرماس وپطروباس و هرمیس و برادرانی که باایشانند سلام نمایید."},{"v":15,"t":"فیلولکس را و جولیه و نیریاس و خواهرش و اولمپاس و همه مقدسانی که با ایشانند سلام برسانید."},{"v":16,"t":"ویکدیگر را به بوسه مقدسانه سلام نمایید. وجمیع کلیساهای مسیح شما را سلام می‌فرستند."},{"v":17,"t":"لکن‌ای برادران از شما استدعا می‌کنم آن کسانی را که منشا تفاریق و لغزشهای مخالف آن تعلیمی که شما یافته‌اید می‌باشند، ملاحظه کنیدو از ایشان اجتناب نمایید."},{"v":18,"t":"زیرا که چنین اشخاص خداوند ما عیسی مسیح را خدمت نمی کنند بلکه شکم خود را و به الفاظ نیکو وسخنان شیرین دلهای ساده دلان را می‌فریبند."},{"v":19,"t":"زیرا که اطاعت شما در جمیع مردم شهرت یافته است. پس درباره شما مسرور شدم. اماآرزوی این دارم که در نیکویی دانا و در بدی ساده دل باشید."},{"v":20,"t":"و خدای سلامتی بزودی شیطان را زیرپایهای شما خواهد سایید. فیض خداوند ما عیسی مسیح با شما باد."},{"v":21,"t":"تیموتاوس همکار من و لوقا و یاسون وسوسیپاطرس که خویشان منند شما را سلام می‌فرستند."},{"v":22,"t":"من طرتیوس، کاتب رساله، شما رادر خداوند سلام می‌گویم."},{"v":23,"t":"قایوس که مرا وتمام کلیسا را میزبان است، شما را سلام می‌فرستد. و ارسطس خزینه دار شهر و کوارطس برادر به شما سلام می‌فرستند."},{"v":24,"t":"الان او را که قادر است که شما را استوار سازد، برحسب بشارت من و موعظه عیسی مسیح، مطابق کشف آن سری که از زمانهای ازلی مخفی بود،"},{"v":25,"t":"لکن درحال مکشوف شد و بوسیله کتب انبیا برحسب فرموده خدای سرمدی به جمیع امت‌ها بجهت اطاعت ایمان آشکارا گردید،"},{"v":26,"t":"خدای حکیم وحید را بوسیله عیسی مسیح تا ابدالاباد جلال باد، آمین."}],"en":[{"v":1,"t":"I commend to you Phoebe, our sister, who is a servant of the assembly that is at Cenchreae,"},{"v":2,"t":"that you receive her in the Lord in a way worthy of the saints, and that you assist her in whatever matter she may need from you, for she herself also has been a helper of many, and of my own self."},{"v":3,"t":"Greet Prisca and Aquila, my fellow workers in Christ Jesus,"},{"v":4,"t":"who risked their own necks for my life, to whom not only I give thanks, but also all the assemblies of the Gentiles."},{"v":5,"t":"Greet the assembly that is in their house. Greet Epaenetus, my beloved, who is the first fruits of Achaia to Christ."},{"v":6,"t":"Greet Mary, who labored much for us."},{"v":7,"t":"Greet Andronicus and Junia, my relatives and my fellow prisoners, who are notable among the apostles, who were also in Christ before me."},{"v":8,"t":"Greet Amplias, my beloved in the Lord."},{"v":9,"t":"Greet Urbanus, our fellow worker in Christ, and Stachys, my beloved."},{"v":10,"t":"Greet Apelles, the approved in Christ. Greet those who are of the household of Aristobulus."},{"v":11,"t":"Greet Herodion, my kinsman. Greet them of the household of Narcissus, who are in the Lord."},{"v":12,"t":"Greet Tryphaena and Tryphosa, who labor in the Lord. Greet Persis, the beloved, who labored much in the Lord."},{"v":13,"t":"Greet Rufus, the chosen in the Lord, and his mother and mine."},{"v":14,"t":"Greet Asyncritus, Phlegon, Hermes, Patrobas, Hermas, and the brothers who are with them."},{"v":15,"t":"Greet Philologus and Julia, Nereus and his sister, and Olympas, and all the saints who are with them."},{"v":16,"t":"Greet one another with a holy kiss. The assemblies of Christ greet you."},{"v":17,"t":"Now I beg you, brothers, look out for those who are causing the divisions and occasions of stumbling, contrary to the doctrine which you learned, and turn away from them."},{"v":18,"t":"For those who are such don’t serve our Lord Jesus Christ, but their own belly; and by their smooth and flattering speech they deceive the hearts of the innocent."},{"v":19,"t":"For your obedience has become known to all. I rejoice therefore over you. But I desire to have you wise in that which is good, but innocent in that which is evil."},{"v":20,"t":"And the God of peace will quickly crush Satan under your feet. The grace of our Lord Jesus Christ be with you."},{"v":21,"t":"Timothy, my fellow worker, greets you, as do Lucius, Jason, and Sosipater, my relatives."},{"v":22,"t":"I, Tertius, who write the letter, greet you in the Lord."},{"v":23,"t":"Gaius, my host and host of the whole assembly, greets you. Erastus, the treasurer of the city, greets you, as does Quartus, the brother."},{"v":24,"t":"The grace of our Lord Jesus Christ be with you all! Amen."}],"hr":[{"v":1,"t":"Preporučujem vam Febu, sestru našu, poslužiteljicu Crkve u Kenhreji:"},{"v":2,"t":"primite je u Gospodinu kako dolikuje svetima i priskočite joj u pomoć u svemu što od vas ustreba jer je i ona bila zaštitnicom mnogima i meni samomu."},{"v":3,"t":"Pozdravite Prisku i Akvilu, suradnike moje u Kristu Isusu."},{"v":4,"t":"Oni su za moj život podmetnuli svoj vrat; zahvaljujem im ne samo ja nego i sve Crkve pogana."},{"v":5,"t":"Pozdravite i Crkvu u njihovoj kući. Pozdravite ljubljenog mi Epeneta koji je prvina Azije za Krista."},{"v":6,"t":"Pozdravite Mariju koja se mnogo trudila za vas."},{"v":7,"t":"Pozdravite Andronika i Juniju, rođake i suuznike moje; oni su ugledni među apostolima i prije mene bili su u Kristu."},{"v":8,"t":"Pozdravite Amplijata, ljubljenoga moga u Gospodinu."},{"v":9,"t":"Pozdravite Urbana, suradnika moga u Kristu, i ljubljenog mi Staha."},{"v":10,"t":"Pozdravite Apela, prokušanoga u Kristu. Pozdravite Aristobulove."},{"v":11,"t":"Pozdravite Herodiona, rođaka moga. Pozdravite Narcisove koji su u Gospodinu."},{"v":12,"t":"Pozdravite Trifenu i Trifozu koje se trude u Gospodinu. Pozdravite ljubljenu Persidu koja se mnogo trudila u Gospodinu."},{"v":13,"t":"Pozdravite Rufa, izabranika u Gospodinu, i majku njegovu i moju."},{"v":14,"t":"Pozdravite Asinkrita, Flegonta, Herma, Patrobu, Hermu i braću koja su s njima."},{"v":15,"t":"Pozdravite Filologa i Juliju, Nereja i njegovu sestru, i Olimpu, i sve svete koji su s njima."},{"v":16,"t":"Pozdravite jedni druge cjelovom svetim. Pozdravljaju vas sve Crkve Kristove."},{"v":17,"t":"Zaklinjem vas, braćo, čuvajte se onih koji siju razdore i sablazni mimo nauk u kojem ste poučeni, i klonite ih se."},{"v":18,"t":"Jer takvi ne služe Gospodinu našemu Kristu, nego svom trbuhu te lijepim i laskavim riječima zavode srca nedužnih."},{"v":19,"t":"Doista, vaša je poslušnost doprla do sviju. Zbog vas se dakle radujem i htio bih da budete mudri za dobro, a bezazleni za zlo."},{"v":20,"t":"Bog mira satrt će ubrzo Sotonu pod vašim nogama. Milost Gospodina Isusa s vama!"},{"v":21,"t":"Pozdravlja vas Timotej, suradnik moj, i Lucije, Jason i Sosipater, rođaci moji."},{"v":22,"t":"Pozdravljam vas u Gospodinu ja, Tercije, koji napisah ovu poslanicu."},{"v":23,"t":"Pozdravlja vas Gaj, gostoprimac moj i cijele Crkve. Pozdravlja vas Erast, gradski blagajnik, i brat Kvart."},{"v":24,"t":"#"},{"v":25,"t":"Onomu koji vas može učvrstiti - po mojem evanđelju i propovijedanju Isusa Krista, po objavljenju Otajstva prešućenog drevnim vremenima,"},{"v":26,"t":"a sada očitovanog i po proročkim pismima odredbom vječnoga Boga svim narodima obznanjenog za poslušnost, vjeru -"},{"v":27,"t":"jedinomu Mudromu, Bogu, po Isusu Kristu: Njemu slava u vijeke! Amen."}]}},"1CO":{"1":{"fa":[{"v":1,"t":"پولس به اراده خدا رسول خوانده شده عیسی مسیح و سوستانیس برادر،"},{"v":2,"t":"به کلیسای خدا که در قرنتس است، ازمقدسین در مسیح عیسی که برای تقدس خوانده شده‌اند، با همه کسانی که در هرجا نام خداوند ماعیسی مسیح را می‌خوانند که (خداوند) ما و(خداوند) ایشان است."},{"v":3,"t":"فیض و سلامتی ازجانب پدر ما خدا و عیسی مسیح خداوند بر شماباد."},{"v":4,"t":"خدای خود را پیوسته شکر می‌کنم درباره شما برای آن فیض خدا که در مسیح عیسی به شما عطا شده است،"},{"v":5,"t":"زیرا شما از هرچیز دروی دولتمند شده‌اید، در هر کلام و در هرمعرفت."},{"v":6,"t":"چنانکه شهادت مسیح در شما استوارگردید،"},{"v":7,"t":"بحدی که در هیچ بخشش ناقص نیستیدو منتظر مکاشفه خداوند ما عیسی مسیح می‌باشید."},{"v":8,"t":"که او نیز شما را تا آخر استوار خواهدفرمود تا در روز خداوند ما عیسی مسیح بی‌ملامت باشید."},{"v":9,"t":"امین است خدایی که شما را به شراکت پسر خود عیسی مسیح خداوند ماخوانده است."},{"v":10,"t":"لکن‌ای برادران از شما استدعا دارم به نام خداوند ما عیسی مسیح که همه یک سخن گوییدو شقاق در میان شما نباشد، بلکه در یک فکر ویک رای کامل شوید."},{"v":11,"t":"زیرا که‌ای برادران من، از اهل خانه خلوئی درباره شما خبر به من رسیدکه نزاعها در میان شما پیدا شده است."},{"v":12,"t":"غرض اینکه هریکی از شما می‌گوید که من از پولس هستم، و من از اپلس، و من از کیفا، و من از مسیح."},{"v":13,"t":"آیا مسیح منقسم شد؟ یا پولس در راه شمامصلوب گردید؟ یا به نام پولس تعمید یافتید؟"},{"v":14,"t":"خدا را شکر می‌کنم که هیچ‌یکی از شما راتعمید ندادم جز کرسپس و قایوس،"},{"v":15,"t":"که مباداکسی گوید که به نام خود تعمید دادم."},{"v":16,"t":"وخاندان استیفان را نیز تعمید دادم و دیگر یادندارم که کسی را تعمید داده باشم."},{"v":17,"t":"زیرا که مسیح مرا فرستاد، نه تا تعمید دهم بلکه تا بشارت رسانم، نه به حکمت کلام مبادا صلیب مسیح باطل شود."},{"v":18,"t":"زیرا ذکر صلیب برای هالکان حماقت است، لکن نزد ما که ناجیان هستیم قوت خداست."},{"v":19,"t":"زیرا مکتوب است: «حکمت حکما را باطل سازم و فهم فهیمان را نابود گردانم.»"},{"v":20,"t":"کجا است حکیم؟ کجا کاتب؟ کجا مباحث این دنیا؟ مگرخدا حکمت جهان را جهالت نگردانیده است؟"},{"v":21,"t":"زیرا که چون برحسب حکمت خدا، جهان ازحکمت خود به معرفت خدا نرسید، خدا بدین رضا داد که بوسیله جهالت موعظه، ایمانداران رانجات‌بخشد."},{"v":22,"t":"چونکه یهود آیتی می‌خواهند ویونانیان طالب حکمت هستند."},{"v":23,"t":"لکن ما به مسیح مصلوب وعظ می‌کنیم که یهود را لغزش و امت هارا جهالت است."},{"v":24,"t":"لکن دعوت‌شدگان را خواه یهود و خواه یونانی مسیح قوت خدا و حکمت خدا است."},{"v":25,"t":"زیرا که جهالت خدا از انسان حکیمتر است و ناتوانی خدا از مردم، تواناتر."},{"v":26,"t":"زیرا‌ای برادران دعوت خود را ملاحظه نمایید که بسیاری بحسب جسم حکیم نیستند وبسیاری توانا نی و بسیاری شریف نی."},{"v":27,"t":"بلکه خدا جهال جهان را برگزید تا حکما را رسوا سازدو خدا ناتوانان عالم را برگزید تا توانایان را رسواسازد،"},{"v":28,"t":"و خسیسان دنیا و محقران را خدابرگزید، بلکه نیستیها را تا هستیها را باطل گرداند."},{"v":29,"t":"تا هیچ بشری در حضور او فخر نکند."},{"v":30,"t":"لکن از او شما هستید در عیسی مسیح که از جانب خدابرای شما حکمت شده است و عدالت قدوسیت و فدا."},{"v":31,"t":"تا چنانکه مکتوب است هر‌که فخر کنددر خداوند فخر نماید."}],"en":[{"v":1,"t":"Paul, called to be an apostle of Jesus Christ through the will of God, and our brother Sosthenes,"},{"v":2,"t":"to the assembly of God which is at Corinth—those who are sanctified in Christ Jesus, called saints, with all who call on the name of our Lord Jesus Christ in every place, both theirs and ours:"},{"v":3,"t":"Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":4,"t":"I always thank my God concerning you for the grace of God which was given you in Christ Jesus,"},{"v":5,"t":"that in everything you were enriched in him, in all speech and all knowledge—"},{"v":6,"t":"even as the testimony of Christ was confirmed in you—"},{"v":7,"t":"so that you come behind in no gift, waiting for the revelation of our Lord Jesus Christ,"},{"v":8,"t":"who will also confirm you until the end, blameless in the day of our Lord Jesus Christ."},{"v":9,"t":"God is faithful, through whom you were called into the fellowship of his Son, Jesus Christ our Lord."},{"v":10,"t":"Now I beg you, brothers, through the name of our Lord, Jesus Christ, that you all speak the same thing, and that there be no divisions among you, but that you be perfected together in the same mind and in the same judgment."},{"v":11,"t":"For it has been reported to me concerning you, my brothers, by those who are from Chloe’s household, that there are contentions among you."},{"v":12,"t":"Now I mean this, that each one of you says, “I follow Paul,” “I follow Apollos,” “I follow Cephas,” and, “I follow Christ.”"},{"v":13,"t":"Is Christ divided? Was Paul crucified for you? Or were you baptized into the name of Paul?"},{"v":14,"t":"I thank God that I baptized none of you except Crispus and Gaius,"},{"v":15,"t":"so that no one should say that I had baptized you into my own name."},{"v":16,"t":"(I also baptized the household of Stephanas; besides them, I don’t know whether I baptized any other.)"},{"v":17,"t":"For Christ sent me not to baptize, but to preach the Good News—not in wisdom of words, so that the cross of Christ wouldn’t be made void."},{"v":18,"t":"For the word of the cross is foolishness to those who are dying, but to us who are being saved it is the power of God."},{"v":19,"t":"For it is written, “I will destroy the wisdom of the wise. I will bring the discernment of the discerning to nothing.”"},{"v":20,"t":"Where is the wise? Where is the scribe? Where is the debater of this age? Hasn’t God made foolish the wisdom of this world?"},{"v":21,"t":"For seeing that in the wisdom of God, the world through its wisdom didn’t know God, it was God’s good pleasure through the foolishness of the preaching to save those who believe."},{"v":22,"t":"For Jews ask for signs, Greeks seek after wisdom,"},{"v":23,"t":"but we preach Christ crucified, a stumbling block to Jews and foolishness to Greeks,"},{"v":24,"t":"but to those who are called, both Jews and Greeks, Christ is the power of God and the wisdom of God;"},{"v":25,"t":"because the foolishness of God is wiser than men, and the weakness of God is stronger than men."},{"v":26,"t":"For you see your calling, brothers, that not many are wise according to the flesh, not many mighty, and not many noble;"},{"v":27,"t":"but God chose the foolish things of the world that he might put to shame those who are wise. God chose the weak things of the world that he might put to shame the things that are strong."},{"v":28,"t":"God chose the lowly things of the world, and the things that are despised, and the things that don’t exist, that he might bring to nothing the things that exist,"},{"v":29,"t":"that no flesh should boast before God."},{"v":30,"t":"Because of him, you are in Christ Jesus, who was made to us wisdom from God, and righteousness and sanctification, and redemption,"},{"v":31,"t":"that, as it is written, “He who boasts, let him boast in the Lord.”"}],"hr":[{"v":1,"t":"Pavao, po Božjoj volji pozvan za apostola Krista Isusa, i brat Sosten"},{"v":2,"t":"Crkvi Božjoj u Korintu - posvećenima u Kristu Isusu, pozvanicima, svetima, sa svima što na bilo kojemu mjestu prizivlju ime Isusa Krista, Gospodina našega, njihova i našega."},{"v":3,"t":"Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista!"},{"v":4,"t":"Zahvaljujem Bogu svojemu svagda za vas zbog milosti Božje koja vam je dana u Kristu Isusu:"},{"v":5,"t":"u njemu se obogatiste u svemu - u svakoj riječi i svakom spoznanju."},{"v":6,"t":"Kako li se svjedočanstvo o Kristu utvrdilo u vama"},{"v":7,"t":"te ne oskudijevate ni na jednom daru čekajući Objavljenje Gospodina našega Isusa Krista!"},{"v":8,"t":"On će vas učiniti i postojanima do kraja, besprigovornima u Dan Gospodina našega Isusa Krista."},{"v":9,"t":"Vjeran je Bog koji vas pozva u zajedništvo Sina svojega Isusa Krista, Gospodina našega."},{"v":10,"t":"Zaklinjem vas, braćo, imenom Gospodina našega Isusa Krista: svi budite iste misli; neka ne bude među vama razdora, nego budite savršeno istog osjećanja i istog mišljenja."},{"v":11,"t":"Jer Klojini mi, braćo moja, o vama rekoše da među vama ima svađa."},{"v":12,"t":"Mislim to što svaki od vas govori: “Ja sam Pavlov”, “A ja Apolonov”, “A ja Kefin”, “A ja Kristov”."},{"v":13,"t":"Zar je Krist razdijeljen? Zar je Pavao raspet za vas? Ili ste u Pavlovo ime kršteni?"},{"v":14,"t":"Hvala Bogu što ne krstih nikoga od vas, osim Krispa i Gaja;"},{"v":15,"t":"da ne bi tko rekao da ste u moje ime kršteni."},{"v":16,"t":"A da, krstih i Stefanin dom. Inače ne znam krstih li koga drugoga."},{"v":17,"t":"Jer ne posla me Krist krstiti, nego navješćivati evanđelje, i to ne mudrošću besjede, da se ne obeskrijepi križ Kristov."},{"v":18,"t":"Uistinu, besjeda o križu ludost je onima koji propadaju, a nama spašenicima sila je Božja."},{"v":19,"t":"Ta pisano je: Upropastit ću mudrost mudrih, i odbacit ću umnost umnih."},{"v":20,"t":"Gdje je mudrac? Gdje je književnik? Gdje je istraživač ovoga svijeta? Zar ne izludi Bog mudrost svijeta?"},{"v":21,"t":"Doista, kad svijet u mudrosti Božjoj Boga ne upozna mudrošću, svidjelo se Bogu ludošću propovijedanja spasiti vjernike."},{"v":22,"t":"Jer i Židovi znake ištu i Grci mudrost traže,"},{"v":23,"t":"a mi propovijedamo Krista raspetoga: Židovima sablazan, poganima ludost,"},{"v":24,"t":"pozvanima pak - i Židovima i Grcima - Krista, Božju snagu i Božju mudrost."},{"v":25,"t":"Jer ludo Božje mudrije je od ljudi i slabo Božje jače je od ljudi."},{"v":26,"t":"Ta gledajte, braćo, sebe, pozvane: nema mnogo mudrih po tijelu, nema mnogo snažnih, nema mnogo plemenitih."},{"v":27,"t":"Nego lude svijeta izabra Bog da posrami mudre, i slabe svijeta izabra Bog da posrami jake;"},{"v":28,"t":"i neplemenite svijeta i prezrene izabra Bog, i ono što nije, da uništi ono što jest,"},{"v":29,"t":"da se nijedan smrtnik ne bi hvalio pred Bogom."},{"v":30,"t":"Od njega je da vi jeste u Kristu Isusu, koji nama posta mudrost od Boga, i pravednost, i posvećenje, i otkupljenje,"},{"v":31,"t":"da bude kako je pisano: Tko se hvali, u Gospodu neka se hvali."}]},"2":{"fa":[{"v":1,"t":"و من‌ای برادران، چون به نزد شما آمدم، با فضیلت کلام یا حکمت نیامدم چون شمارا به‌سر خدا اعلام می‌نمودم."},{"v":2,"t":"زیرا عزیمت نکردم که چیزی در میان شما دانسته باشم جزعیسی مسیح و او را مصلوب."},{"v":3,"t":"و من در ضعف وترس و لرزش بسیار نزد شما شدم،"},{"v":4,"t":"و کلام ووعظ من به سخنان مقنع حکمت نبود، بلکه به برهان روح و قوت،"},{"v":5,"t":"تا ایمان شما در حکمت انسان نباشد بلکه در قوت خدا."},{"v":6,"t":"لکن حکمتی بیان می‌کنیم نزد کاملین، اماحکمتی که از این عالم نیست و نه از روسای این عالم که زایل می‌گردند."},{"v":7,"t":"بلکه حکمت خدا را درسری بیان می‌کنیم، یعنی آن حکمت مخفی را که خدا پیش از دهرها برای جلال ما مقدر فرمود،"},{"v":8,"t":"که احدی از روسای این عالم آن را ندانست زیرا اگر می‌دانستند خداوند جلال را مصلوب نمی کردند."},{"v":9,"t":"بلکه چنانکه مکتوب است: «چیزهایی را که چشمی ندید و گوشی نشنید و به‌خاطر انسانی خطور نکرد، یعنی آنچه خدا برای دوستداران خود مهیا کرده است.»"},{"v":10,"t":"اما خدا آنهارا به روح خود بر ما کشف نموده است، زیرا که روح همه‌چیز حتی عمقهای خدا را نیز تفحص می‌کند."},{"v":11,"t":"زیرا کیست از مردمان که امور انسان رابداند جز روح انسان که در وی می‌باشد. همچنین نیز امور خدا را هیچ‌کس ندانسته است، جز روح خدا."},{"v":12,"t":"لیکن ما روح جهان را نیافته‌ایم، بلکه آن روح که از خداست تا آنچه خدا به ما عطا فرموده است بدانیم."},{"v":13,"t":"که آنها را نیز بیان می‌کنیم نه به سخنان آموخته شده از حکمت انسان، بلکه به آنچه روح‌القدس می‌آموزد و روحانیها را باروحانیها جمع می‌نماییم."},{"v":14,"t":"اما انسان نفسانی‌امور روح خدا را نمی پذیرد زیرا که نزد او جهالت است و آنها را نمی تواند فهمید زیرا حکم آنها ازروح می‌شود."},{"v":15,"t":"لکن شخص روحانی در همه‌چیز حکم می‌کند و کسی را در او حکم نیست."},{"v":16,"t":"«زیرا کیست که فکر خداوند را دانسته باشد تااو را تعلیم دهد؟» لکن ما فکر مسیح را داریم."}],"en":[{"v":1,"t":"When I came to you, brothers, I didn’t come with excellence of speech or of wisdom, proclaiming to you the testimony of God."},{"v":2,"t":"For I determined not to know anything among you except Jesus Christ and him crucified."},{"v":3,"t":"I was with you in weakness, in fear, and in much trembling."},{"v":4,"t":"My speech and my preaching were not in persuasive words of human wisdom, but in demonstration of the Spirit and of power,"},{"v":5,"t":"that your faith wouldn’t stand in the wisdom of men, but in the power of God."},{"v":6,"t":"We speak wisdom, however, among those who are full grown, yet a wisdom not of this world nor of the rulers of this world who are coming to nothing."},{"v":7,"t":"But we speak God’s wisdom in a mystery, the wisdom that has been hidden, which God foreordained before the worlds for our glory,"},{"v":8,"t":"which none of the rulers of this world has known. For had they known it, they wouldn’t have crucified the Lord of glory."},{"v":9,"t":"But as it is written, “Things which an eye didn’t see, and an ear didn’t hear, which didn’t enter into the heart of man, these God has prepared for those who love him.”"},{"v":10,"t":"But to us, God revealed them through the Spirit. For the Spirit searches all things, yes, the deep things of God."},{"v":11,"t":"For who among men knows the things of a man except the spirit of the man which is in him? Even so, no one knows the things of God except God’s Spirit."},{"v":12,"t":"But we received not the spirit of the world, but the Spirit which is from God, that we might know the things that were freely given to us by God."},{"v":13,"t":"We also speak these things, not in words which man’s wisdom teaches but which the Holy Spirit teaches, comparing spiritual things with spiritual things."},{"v":14,"t":"Now the natural man doesn’t receive the things of God’s Spirit, for they are foolishness to him; and he can’t know them, because they are spiritually discerned."},{"v":15,"t":"But he who is spiritual discerns all things, and he himself is to be judged by no one."},{"v":16,"t":"“For who has known the mind of the Lord that he should instruct him?” But we have Christ’s mind."}],"hr":[{"v":1,"t":"I ja kada dođoh k vama, braćo, ne dođoh s uzvišenom besjedom ili mudrošću navješćivati vam svjedočanstvo Božje"},{"v":2,"t":"jer ne htjedoh među vama znati što drugo osim Isusa Krista, i to raspetoga."},{"v":3,"t":"I ja priđoh k vama slab, u strahu i u veliku drhtanju."},{"v":4,"t":"I besjeda moja i propovijedanje moje ne bijaše u uvjerljivim riječima mudrosti, nego u pokazivanju Duha i snage"},{"v":5,"t":"da se vjera vaša ne temelji na mudrosti ljudskoj nego na snazi Božjoj."},{"v":6,"t":"Mudrost doduše navješćujemo među zrelima, ali ne mudrost ovoga svijeta, ni knezova ovoga svijeta koji propadaju,"},{"v":7,"t":"nego navješćujemo Mudrost Božju, u Otajstvu, sakrivenu; onu koju predodredi Bog prije vjekova za slavu našu,"},{"v":8,"t":"a koje nijedan od knezova ovoga svijeta nije upoznao. Jer da su je upoznali, ne bi Gospodina slave razapeli."},{"v":9,"t":"Nego, kako je pisano: Što oko ne vidje, i uho ne ču, i u srce čovječje ne uđe, to pripravi Bog onima koji ga ljube."},{"v":10,"t":"A nama to Bog objavi po Duhu jer Duh sve proniče, i dubine Božje."},{"v":11,"t":"Jer tko od ljudi zna što je u čovjeku osim duha čovječjega u njemu? Tako i što je u Bogu, nitko ne zna osim Duha Božjega."},{"v":12,"t":"A mi, mi ne primismo duha svijeta, nego Duha koji je od Boga da znamo čime nas je obdario Bog."},{"v":13,"t":"To i navješćujemo, ne naučenim riječima čovječje mudrosti, nego naukom Duha izlažući duhovno duhovnima."},{"v":14,"t":"Naravan čovjek ne prima što je od Duha Božjega; njemu je to ludost i ne može spoznati jer po Duhu valja prosuđivati."},{"v":15,"t":"Duhovan pak prosuđuje sve, a njega nitko ne prosuđuje."},{"v":16,"t":"Jer tko spozna misao Gospodnju, tko da ga pouči? A mi imamo misao Kristovu."}]},"3":{"fa":[{"v":1,"t":"و من‌ای برادران نتوانستم به شما سخن گویم چون روحانیان، بلکه چون جسمانیان و چون اطفال در مسیح."},{"v":2,"t":"و شما را به شیر خوراک دادم نه به گوشت زیرا که هنوزاستطاعت آن نداشتید بلکه الحال نیز ندارید،"},{"v":3,"t":"زیرا که تا به حال جسمانی هستید، چون در میان شما حسد و نزاع و جدایی‌ها است. آیا جسمانی نیستید و به طریق انسان رفتار نمی نمایید؟"},{"v":4,"t":"زیراچون یکی گوید من از پولس و دیگری من از اپلس هستم، آیا انسان نیستید؟"},{"v":5,"t":"پس کیست پولس و کیست اپلس؟ جزخادمانی که بواسطه ایشان ایمان آوردید و به اندازه‌ای که خداوند به هرکس داد."},{"v":6,"t":"من کاشتم واپلس آبیاری کرد لکن خدا نمو می‌بخشید."},{"v":7,"t":"لهذانه کارنده چیزی است و نه آب دهنده بلکه خدای رویاننده."},{"v":8,"t":"و کارنده و سیرآب کننده‌یک هستند، لکن هر یک اجرت خود را بحسب مشقت خودخواهند یافت."},{"v":9,"t":"زیرا با خدا همکاران هستیم وشما زراعت خدا و عمارت خدا هستید."},{"v":10,"t":"بحسب فیض خدا که به من عطا شد، چون معمار دانا بنیاد نهادم و دیگری بر آن عمارت می‌سازد؛ لکن هرکس با‌خبر باشد که چگونه عمارت می‌کند."},{"v":11,"t":"زیرا بنیادی دیگر هیچ‌کس نمی تواند نهاد جز آنکه نهاده شده است، یعنی عیسی مسیح."},{"v":12,"t":"لکن اگر کسی بر آن بنیاد، عمارتی از طلا یا نقره یا جواهر یا چوب یا گیاه یاکاه بنا کند،"},{"v":13,"t":"کار هرکس آشکار خواهد شد، زیرا که آن روز آن را ظاهر خواهد نمود، چونکه آن به آتش به ظهور خواهد رسید و خود آتش، عمل هرکس را خواهد آزمود که چگونه است."},{"v":14,"t":"اگر کاری که کسی بر آن گذارده باشد بماند، اجر خواهد یافت."},{"v":15,"t":"و اگر عمل کسی سوخته شود، زیان بدو وارد آید، هرچند خود نجات یابداما چنانکه از میان آتش."},{"v":16,"t":"آیا نمی دانید که هیکل خدا هستید و روح خدا در شما ساکن است؟"},{"v":17,"t":"اگر کسی هیکل خدارا خراب کند، خدا او را هلاک سازد زیرا هیکل خدا مقدس است و شما آن هستید."},{"v":18,"t":"زنهارکسی خود را فریب ندهد! اگر کسی از شما خودرا در این جهان حکیم پندارد، جاهل بشود تاحکیم گردد."},{"v":19,"t":"زیرا حکمت این جهان نزد خداجهالت است، چنانکه مکتوب است: «حکما را به مکر خودشان گرفتار می‌سازد.»"},{"v":20,"t":"و ایض: «خداوند افکار حکما را می‌داند که باطل است.»"},{"v":21,"t":"پس هیچ‌کس در انسان فخر نکند، زیراهمه‌چیز از آن شما است:"},{"v":22,"t":"خواه پولس، خواه اپلس، خواه کیفا، خواه دنیا، خواه زندگی، خواه موت، خواه چیزهای حال، خواه چیزهای آینده، همه از آن شما است،"},{"v":23,"t":"و شما از مسیح و مسیح از خدا می‌باشد."}],"en":[{"v":1,"t":"Brothers, I couldn’t speak to you as to spiritual, but as to fleshly, as to babies in Christ."},{"v":2,"t":"I fed you with milk, not with solid food, for you weren’t yet ready. Indeed, you aren’t ready even now,"},{"v":3,"t":"for you are still fleshly. For insofar as there is jealousy, strife, and factions among you, aren’t you fleshly, and don’t you walk in the ways of men?"},{"v":4,"t":"For when one says, “I follow Paul,” and another, “I follow Apollos,” aren’t you fleshly?"},{"v":5,"t":"Who then is Apollos, and who is Paul, but servants through whom you believed, and each as the Lord gave to him?"},{"v":6,"t":"I planted. Apollos watered. But God gave the increase."},{"v":7,"t":"So then neither he who plants is anything, nor he who waters, but God who gives the increase."},{"v":8,"t":"Now he who plants and he who waters are the same, but each will receive his own reward according to his own labor."},{"v":9,"t":"For we are God’s fellow workers. You are God’s farming, God’s building."},{"v":10,"t":"According to the grace of God which was given to me, as a wise master builder I laid a foundation, and another builds on it. But let each man be careful how he builds on it."},{"v":11,"t":"For no one can lay any other foundation than that which has been laid, which is Jesus Christ."},{"v":12,"t":"But if anyone builds on the foundation with gold, silver, costly stones, wood, hay, or straw,"},{"v":13,"t":"each man’s work will be revealed. For the Day will declare it, because it is revealed in fire; and the fire itself will test what sort of work each man’s work is."},{"v":14,"t":"If any man’s work remains which he built on it, he will receive a reward."},{"v":15,"t":"If any man’s work is burned, he will suffer loss, but he himself will be saved, but as through fire."},{"v":16,"t":"Don’t you know that you are God’s temple and that God’s Spirit lives in you?"},{"v":17,"t":"If anyone destroys God’s temple, God will destroy him; for God’s temple is holy, which you are."},{"v":18,"t":"Let no one deceive himself. If anyone thinks that he is wise among you in this world, let him become a fool that he may become wise."},{"v":19,"t":"For the wisdom of this world is foolishness with God. For it is written, “He has taken the wise in their craftiness.”"},{"v":20,"t":"And again, “The Lord knows the reasoning of the wise, that it is worthless.”"},{"v":21,"t":"Therefore let no one boast in men. For all things are yours,"},{"v":22,"t":"whether Paul, or Apollos, or Cephas, or the world, or life, or death, or things present, or things to come. All are yours,"},{"v":23,"t":"and you are Christ’s, and Christ is God’s."}],"hr":[{"v":1,"t":"I ja, braćo, nisam mogao govoriti vama kao duhovnima, nego kao tjelesnima, kao nejačadi u Kristu."},{"v":2,"t":"Mlijekom vas napojih, ne jelom: još ne mogoste, a ni sada još ne možete"},{"v":3,"t":"jer još ste tjelesni. Doista, dok je među vama zavist i prepiranje, zar niste tjelesni, zar po ljudsku ne postupate?"},{"v":4,"t":"Jer kad jedan govori: “Ja sam Pavlov”, a drugi: “Ja Apolonov”, niste li odveć ljudi?"},{"v":5,"t":"Ta što je Apolon? Što je Pavao? Poslužitelji po kojima povjerovaste - kako već komu Gospodin dade."},{"v":6,"t":"Ja zasadih, Apolon zali, ali Bog dade rasti."},{"v":7,"t":"Tako niti je što onaj tko sadi ni onaj tko zalijeva, nego Bog koji daje rasti."},{"v":8,"t":"Tko sadi i tko zalijeva, jedno su; a svaki će po svome trudu primiti plaću."},{"v":9,"t":"Jer Božji smo suradnici: Božja ste njiva, Božja građevina."},{"v":10,"t":"Po milosti Božjoj koja mi je dana ja kao mudri graditelj postavih temelj, a drugi naziđuje; ali svaki neka pazi kako naziđuje."},{"v":11,"t":"Jer nitko ne može postaviti drugoga temelja osim onoga koji je postavljen, a taj je Isus Krist."},{"v":12,"t":"Naziđuje li tko na ovom temelju zlatom, srebrom, dragim kamenjem, drvom, sijenom, slamom -"},{"v":13,"t":"svačije će djelo izići na svjetlo. Onaj će Dan pokazati jer će se u ognju očitovati. I kakvo je čije djelo, oganj će iskušati."},{"v":14,"t":"Ostane li djelo, primit će plaću onaj tko ga je nazidao."},{"v":15,"t":"Izgori li čije djelo, taj će štetovati; ipak, on će se sam spasiti, ali kao kroz oganj."},{"v":16,"t":"Ne znate li? Hram ste Božji i Duh Božji prebiva u vama."},{"v":17,"t":"Ako tko upropašćuje hram Božji, upropastit će njega Bog. Jer hram je Božji svet, a to ste vi."},{"v":18,"t":"Nitko neka se ne vara. Ako tko misli da je mudar među vama na ovome svijetu, neka bude lud da bude mudar."},{"v":19,"t":"Jer mudrost ovoga svijeta ludost je pred Bogom. Ta pisano je: On hvata mudre u njihovu lukavstvu."},{"v":20,"t":"I opet: Gospodin poznaje namisli mudrih, one su isprazne."},{"v":21,"t":"Zato neka se nitko ne hvasta ljudima jer sve je vaše."},{"v":22,"t":"Bio Pavao, ili Apolon, ili Kefa, bio svijet, ili život, ili smrt, ili sadašnje, ili buduće: sve je vaše,"},{"v":23,"t":"vi Kristovi, a Krist Božji."}]},"4":{"fa":[{"v":1,"t":"هرکس ما را چون خدام مسیح و وکلای اسرار خدا بشمارد."},{"v":2,"t":"و دیگر در وکلابازپرس می‌شود که هر یکی امین باشد."},{"v":3,"t":"امابجهت من کمتر چیزی است که از شما یا از یوم بشر حکم کرده شوم، بلکه برخود نیز حکم نمی کنم."},{"v":4,"t":"زیرا که در خود عیبی نمی بینم، لکن ازاین عادل شمرده نمی شوم، بلکه حکم کننده من خداوند است."},{"v":5,"t":"لهذا پیش از وقت به چیزی حکم مکنید تا خداوند بیاید که خفایای ظلمت راروشن خواهد کرد و نیتهای دلها را به ظهورخواهد آورد؛ آنگاه هرکس را مدح از خدا خواهدبود."},{"v":6,"t":"اما‌ای برادران، این چیزها را بطور مثل به خود و اپلس نسبت دادم به‌خاطر شما تا درباره ماآموخته شوید که از آنچه مکتوب است تجاوزنکنید و تا هیچ‌یکی از شما تکبر نکند برای یکی بر دیگری."},{"v":7,"t":"زیرا کیست که تو را برتری داد وچه چیز داری که نیافتی؟ پس چون یافتی، چرافخر می‌کنی که گویا نیافتی."},{"v":8,"t":"الحال سیر شده و دولتمند گشته‌اید و بدون ما سلطنت می‌کنید؛ و کاشکه سلطنت می‌کردیدتا ما نیز با شما سلطنت می‌کردیم."},{"v":9,"t":"زیرا گمان می‌برم که خدا ما رسولان را آخر همه عرضه داشت مثل آنانی که فتوای موت بر ایشان شده است، زیرا که جهان و فرشتگان و مردم راتماشاگاه شده‌ایم."},{"v":10,"t":"ما به‌خاطر مسیح جاهل هستیم، لکن شما در مسیح دانا هستید؛ ما ضعیف لکن شما توانا؛ شما عزیز اما ما ذلیل."},{"v":11,"t":"تا به همین ساعت گرسنه و تشنه و عریان و کوبیده وآواره هستیم،"},{"v":12,"t":"و به‌دستهای خود کار کرده، مشقت می‌کشیم و دشنام شنیده، برکت می‌طلبیم و مظلوم گردیده، صبر می‌کنیم."},{"v":13,"t":"چون افترا بر مامی زنند، نصیحت می‌کنیم و مثل قاذورات دنیا وفضلات همه‌چیز شده‌ایم تا به حال."},{"v":14,"t":"و این را نمی نویسم تا شما را شرمنده سازم بلکه چون فرزندان محبوب خود تنبیه می‌کنم."},{"v":15,"t":"زیرا هرچند هزاران استاد در مسیح داشته باشید، لکن پدران بسیار ندارید، زیرا که من شما رادر مسیح عیسی به انجیل تولید نمودم،"},{"v":16,"t":"پس ازشما التماس می‌کنم که به من اقتدا نمایید."},{"v":17,"t":"برای همین تیموتاوس را نزد شما فرستادم که اوست فرزند محبوب من و امین در خداوند تا راههای مرا در مسیح به یاد شما بیاورد، چنانکه در هرجاو در هرکلیسا تعلیم می‌دهم."},{"v":18,"t":"اما بعضی تکبرمی کنند به گمان آنکه من نزد شما نمی آیم."},{"v":19,"t":"لکن به زودی نزد شما خواهم آمد، اگرخداوند بخواهد و خواهم دانست نه سخن متکبران را بلکه قوت ایشان را."},{"v":20,"t":"زیرا ملکوت خدا به زبان نیست بلکه در قوت است."},{"v":21,"t":"چه خواهش دارید آیا با چوب نزد شما بیایم یا بامحبت و روح حلم؟"}],"en":[{"v":1,"t":"So let a man think of us as Christ’s servants and stewards of God’s mysteries."},{"v":2,"t":"Here, moreover, it is required of stewards that they be found faithful."},{"v":3,"t":"But with me it is a very small thing that I should be judged by you, or by a human court. Yes, I don’t even judge my own self."},{"v":4,"t":"For I know nothing against myself. Yet I am not justified by this, but he who judges me is the Lord."},{"v":5,"t":"Therefore judge nothing before the time, until the Lord comes, who will both bring to light the hidden things of darkness and reveal the counsels of the hearts. Then each man will get his praise from God."},{"v":6,"t":"Now these things, brothers, I have in a figure transferred to myself and Apollos for your sakes, that in us you might learn not to think beyond the things which are written, that none of you be puffed up against one another."},{"v":7,"t":"For who makes you different? And what do you have that you didn’t receive? But if you did receive it, why do you boast as if you had not received it?"},{"v":8,"t":"You are already filled. You have already become rich. You have come to reign without us. Yes, and I wish that you did reign, that we also might reign with you!"},{"v":9,"t":"For I think that God has displayed us, the apostles, last of all, like men sentenced to death. For we are made a spectacle to the world, both to angels and men."},{"v":10,"t":"We are fools for Christ’s sake, but you are wise in Christ. We are weak, but you are strong. You have honor, but we have dishonor."},{"v":11,"t":"Even to this present hour we hunger, thirst, are naked, are beaten, and have no certain dwelling place."},{"v":12,"t":"We toil, working with our own hands. When people curse us, we bless. Being persecuted, we endure."},{"v":13,"t":"Being defamed, we entreat. We are made as the filth of the world, the dirt wiped off by all, even until now."},{"v":14,"t":"I don’t write these things to shame you, but to admonish you as my beloved children."},{"v":15,"t":"For though you have ten thousand tutors in Christ, you don’t have many fathers. For in Christ Jesus, I became your father through the Good News."},{"v":16,"t":"I beg you therefore, be imitators of me."},{"v":17,"t":"Because of this I have sent Timothy to you, who is my beloved and faithful child in the Lord, who will remind you of my ways which are in Christ, even as I teach everywhere in every assembly."},{"v":18,"t":"Now some are puffed up, as though I were not coming to you."},{"v":19,"t":"But I will come to you shortly, if the Lord is willing. And I will know, not the word of those who are puffed up, but the power."},{"v":20,"t":"For God’s Kingdom is not in word, but in power."},{"v":21,"t":"What do you want? Shall I come to you with a rod, or in love and a spirit of gentleness?"}],"hr":[{"v":1,"t":"Tako, neka nas svatko smatra službenicima Kristovim i upraviteljima otajstava Božjih."},{"v":2,"t":"A od upravitelja iziskuje se napokon da budu vjerni."},{"v":3,"t":"Meni pak nije nimalo do toga da me sudite vi ili bilo koji ljudski sud; a ni ja sam sebe ne sudim."},{"v":4,"t":"Doista, ničega sebi nisam svjestan, no time nisam opravdan: moj je sudac Gospodin."},{"v":5,"t":"Zato ne sudite ništa prije vremena dok ne dođe Gospodin koji će iznijeti na vidjelo što je sakriveno u tami i razotkriti nakane srdaca. I tada će svatko primiti pohvalu od Boga."},{"v":6,"t":"Time, braćo, smjerah na sebe i Apolona radi vas: da na nama naučite onu “Ne preko onoga što je pisano” te se ne nadimate jednim protiv drugoga."},{"v":7,"t":"Ta tko tebi daje prednost? Što imaš da nisi primio? Ako si primio, što se hvastaš kao da nisi primio?"},{"v":8,"t":"Već ste siti, već se obogatiste, bez nas se zakraljiste! Kamo sreće da se zakraljiste da i mi s vama zajedno kraljujemo!"},{"v":9,"t":"Jer Bog je, čini mi se, nas apostole prikazao posljednje, kao na smrt osuđene, jer postali smo prizor svijetu, i anđelima, i ljudima -"},{"v":10,"t":"mi ludi poradi Krista, vi mudri u Kristu; mi slabi, vi jaki; vi čašćeni, mi prezreni;"},{"v":11,"t":"sve do ovoga časa i gladujemo, i žeđamo, i goli smo, i pljuskaju nas, i beskućnici smo,"},{"v":12,"t":"i patimo se radeći svojim rukama. Proklinjani blagoslivljamo, proganjani ustrajavamo,"},{"v":13,"t":"pogrđivani tješimo. Kao smeće svijeta postasmo, svačiji izmet sve do sada."},{"v":14,"t":"Ne pišem ovoga da vas postidim, nego da vas kao ljubljenu svoju djecu urazumim."},{"v":15,"t":"Jer da imate u Kristu i deset tisuća učitelja, ipak ne biste imali više otaca. Ta u Kristu Isusu po evanđelju ja vas rodih!"},{"v":16,"t":"Zaklinjem vas, dakle: nasljedovatelji moji budite."},{"v":17,"t":"Zato upravo poslah k vama Timoteja, koji mi je dijete ljubljeno i vjerno u Gospodinu, da vas podsjeti na naputke moje, u Kristu, kako posvuda u svakoj crkvi učim."},{"v":18,"t":"Neki se uzniješe kao da ja neću doći k vama."},{"v":19,"t":"Ipak, eto me ubrzo k vama, ako Gospodin htjedne, i rasudit ću ne riječi onih nadutih, nego krepost."},{"v":20,"t":"Ta nije u riječi kraljevstvo Božje, nego u kreposti."},{"v":21,"t":"Što želite? Da k vama dođem sa šibom ili s ljubavlju i duhom blagosti?"}]},"5":{"fa":[{"v":1,"t":"فی الحقیقه شنیده می‌شود که در میان شمازنا پیدا شده است، و چنان زنایی که درمیان امت‌ها هم نیست؛ که شخصی زن پدر خود را داشته باشد."},{"v":2,"t":"و شما فخر می‌کنید بلکه ماتم هم ندارید، چنانکه باید تا آن کسی‌که این عمل را کرداز میان شما بیرون شود."},{"v":3,"t":"زیرا که من هرچند درجسم غایبم، اما در روح حاضرم؛ و الان چون حاضر، حکم کردم در حق کسی‌که این را چنین کرده است."},{"v":4,"t":"به نام خداوند ما عیسی مسیح، هنگامی که شما با روح من با قوت خداوند ماعیسی مسیح جمع شوید،"},{"v":5,"t":"که چنین شخص به شیطان سپرده شود بجهت هلاکت جسم تا روح در روز خداوند عیسی نجات یابد."},{"v":6,"t":"فخر شما نیکو نیست. آیا آگاه نیستید که اندک خمیرمایه، تمام خمیر را مخمر می‌سازد؟"},{"v":7,"t":"پس خود را از خمیرمایه کهنه پاک سازید تافطیر تازه باشید، چنانکه بی‌خمیرمایه هستید زیراکه فصح ما مسیح در راه ما ذبح شده است."},{"v":8,"t":"پس عید را نگاه داریم نه به خمیرمایه کهنه و نه به خمیرمایه بدی و شرارت، بلکه به فطیر ساده دلی و راستی."},{"v":9,"t":"در آن رساله به شما نوشتم که با زانیان معاشرت نکنید."},{"v":10,"t":"لکن نه مطلق با زانیان این جهان یا طمعکاران و یا ستمکاران یا بت‌پرستان، که در این صورت می‌باید از دنیا بیرون شوید."},{"v":11,"t":"لکن الان به شما می‌نویسم که اگر کسی‌که به برادر نامیده می‌شود، زانی یا طماع یا بت‌پرست یافحاش یا میگسار یا ستمگر باشد، با چنین شخص معاشرت مکنید بلکه غذا هم مخورید."},{"v":12,"t":"زیرا مرا چه‌کار است که بر آنانی که خارج اندداوری کنم. آیا شما بر اهل داخل داوری نمی کنید؟"},{"v":13,"t":"لکن آنانی را که خارج‌اند خدا داوری خواهد کرد. پس آن شریر را از میان خودبرانید."}],"en":[{"v":1,"t":"It is actually reported that there is sexual immorality among you, and such sexual immorality as is not even named among the Gentiles, that one has his father’s wife."},{"v":2,"t":"You are arrogant, and didn’t mourn instead, that he who had done this deed might be removed from among you."},{"v":3,"t":"For I most certainly, as being absent in body but present in spirit, have already, as though I were present, judged him who has done this thing."},{"v":4,"t":"In the name of our Lord Jesus Christ, when you are gathered together with my spirit with the power of our Lord Jesus Christ,"},{"v":5,"t":"you are to deliver such a one to Satan for the destruction of the flesh, that the spirit may be saved in the day of the Lord Jesus."},{"v":6,"t":"Your boasting is not good. Don’t you know that a little yeast leavens the whole lump?"},{"v":7,"t":"Purge out the old yeast, that you may be a new lump, even as you are unleavened. For indeed Christ, our Passover, has been sacrificed in our place."},{"v":8,"t":"Therefore let’s keep the feast, not with old yeast, neither with the yeast of malice and wickedness, but with the unleavened bread of sincerity and truth."},{"v":9,"t":"I wrote to you in my letter to have no company with sexual sinners;"},{"v":10,"t":"yet not at all meaning with the sexual sinners of this world, or with the covetous and extortionists, or with idolaters, for then you would have to leave the world."},{"v":11,"t":"But as it is, I wrote to you not to associate with anyone who is called a brother who is a sexual sinner, or covetous, or an idolater, or a slanderer, or a drunkard, or an extortionist. Don’t even eat with such a person."},{"v":12,"t":"For what do I have to do with also judging those who are outside? Don’t you judge those who are within?"},{"v":13,"t":"But those who are outside, God judges. “Put away the wicked man from among yourselves.”"}],"hr":[{"v":1,"t":"Općenito se čuje o bludnosti među vama, i to takvoj bludnosti kakve nema ni među poganima: da netko ima očevu ženu."},{"v":2,"t":"I vi mi se uznijeli, mjesto da žalujete pa da se iskorijeni iz vaše sredine onaj koji takvo djelo počini."},{"v":3,"t":"A ja, i nenazočan tijelom, ali nazočan duhom, već sam presudio kao nazočan onoga koji je takvo što počinio."},{"v":4,"t":"Pošto se u ime Gospodina našega Isusa Krista okupite vi i moj duh, snagom Gospodina našega Isusa,"},{"v":5,"t":"neka se takav preda Sotoni na propast tijela da bi se spasio duh u Dan Gospodina Isusa."},{"v":6,"t":"Ne valja vam hvastanje! Zar ne znate da malo kvasca sve tijesto ukvasa?"},{"v":7,"t":"Očistite stari kvasac da budete novo tijesto, kao što i jeste beskvasni jer već je žrtvovana Pasha naša, Krist."},{"v":8,"t":"Zato svetkujmo, ne sa starim kvascem ni s kvascem zloće i pakosti, nego s beskvasnim kruhovima čistoće i istine."},{"v":9,"t":"Napisah vam u poslanici da se ne miješate s bludnicima -"},{"v":10,"t":"ne općenito s bludnicima ovoga svijeta, ili lakomcima, ili razbojnicima, ili idolopoklonicima jer biste inače morali iz svijeta izići."},{"v":11,"t":"Napisah vam zapravo da se ne miješate s nazovibratom koji bi bio bludnik, ili lakomac, ili idolopoklonik, ili pogrđivač, ili pijanica, ili razbojnik. S takvim ni za stol!"},{"v":12,"t":"Što spada na me suditi one vani? Ne sudite li vi one koji su unutra?"},{"v":13,"t":"A one vani sudit će Bog. Iskorijenite opakoga iz svoje sredine."}]},"6":{"fa":[{"v":1,"t":"آیا کسی از شما چون بر دیگری مدعی باشد، جرات دارد که مرافعه برد پیش ظالمان نه نزد مقدسان؟"},{"v":2,"t":"یا نمی دانید که مقدسان، دنیا را داوری خواهند کرد؛ و اگر دنیا از شما حکم یابد، آیا قابل مقدمات کمتر نیستید؟"},{"v":3,"t":"آیانمی دانید که فرشتگان را داوری خواهیم کرد تاچه رسد به امور روزگار؟"},{"v":4,"t":"پس چون در مقدمات روزگار مرافعه دارید، آیا آنانی را که در کلیساحقیر شمرده می‌شوند، می‌نشانید؟"},{"v":5,"t":"بجهت انفعال شما می‌گویم، آیا در میان شما یک نفر دانانیست که بتواند در میان برادران خود حکم کند؟"},{"v":6,"t":"بلکه برادر با برادر به محاکمه می‌رود و آن هم نزد بی‌ایمانان!"},{"v":7,"t":"بلکه الان شما را بالکلیه قصوری است که بایکدیگر مرافعه دارید. چرا بیشتر مظلوم نمی شوید و چرا بیشتر مغبون نمی شوید؟"},{"v":8,"t":"بلکه شما ظلم می‌کنید و مغبون می‌سازید و این را نیزبه برادران خود!"},{"v":9,"t":"آیا نمی دانید که ظالمان وارث ملکوت خدا نمی شوند؟ فریب مخورید، زیرافاسقان و بت‌پرستان و زانیان و متنعمان و لواط"},{"v":10,"t":"و دزدان و طمعکاران و میگساران و فحاشان وستمگران وارث ملکوت خدا نخواهند شد."},{"v":11,"t":"وبعضی از شما چنین می‌بودید لکن غسل یافته ومقدس گردیده و عادل کرده شده‌اید به نام عیسی خداوند و به روح خدای ما."},{"v":12,"t":"همه‌چیز برای من جایز است لکن هرچیزمفید نیست. همه‌چیز برای من رواست، لیکن نمی گذارم که چیزی بر من تسلط یابد."},{"v":13,"t":"خوراک برای شکم است و شکم برای خوراک، لکن خدااین و آن را فانی خواهد ساخت. اما جسم برای زنانیست، بلکه برای خداوند است و خداوند برای جسم."},{"v":14,"t":"و خدا خداوند را برخیزانید و ما را نیز به قوت خود خواهد برخیزانید."},{"v":15,"t":"آیا نمی دانید که بدنهای شما اعضای مسیح است؟ پس آیااعضای مسیح را برداشته، اعضای فاحشه گردانم؟ حاشا!"},{"v":16,"t":"آیا نمی دانید که هرکه با فاحشه پیوندد، با وی یکتن باشد؟ زیرا می‌گوید «هردویک تن خواهند بود»."},{"v":17,"t":"لکن کسی‌که با خداوندپیوندد یکروح است."},{"v":18,"t":"از زنا بگریزید. هر گناهی که آدمی می‌کند بیرون از بدن است، لکن زانی بربدن خود گناه می‌ورزد."},{"v":19,"t":"یا نمی دانید که بدن شما هیکل روح‌القدس است که در شما است که از خدا یافته‌اید و از آن خود نیستید؟"},{"v":20,"t":"زیرا که به قیمتی خریده شدید، پس خدا را به بدن خودتمجید نمایید."}],"en":[{"v":1,"t":"Dare any of you, having a matter against his neighbor, go to law before the unrighteous, and not before the saints?"},{"v":2,"t":"Don’t you know that the saints will judge the world? And if the world is judged by you, are you unworthy to judge the smallest matters?"},{"v":3,"t":"Don’t you know that we will judge angels? How much more, things that pertain to this life?"},{"v":4,"t":"If then you have to judge things pertaining to this life, do you set them to judge who are of no account in the assembly?"},{"v":5,"t":"I say this to move you to shame. Isn’t there even one wise man among you who would be able to decide between his brothers?"},{"v":6,"t":"But brother goes to law with brother, and that before unbelievers!"},{"v":7,"t":"Therefore it is already altogether a defect in you that you have lawsuits one with another. Why not rather be wronged? Why not rather be defrauded?"},{"v":8,"t":"No, but you yourselves do wrong and defraud, and that against your brothers."},{"v":9,"t":"Or don’t you know that the unrighteous will not inherit God’s Kingdom? Don’t be deceived. Neither the sexually immoral, nor idolaters, nor adulterers, nor male prostitutes, nor homosexuals,"},{"v":10,"t":"nor thieves, nor covetous, nor drunkards, nor slanderers, nor extortionists, will inherit God’s Kingdom."},{"v":11,"t":"Some of you were such, but you were washed. You were sanctified. You were justified in the name of the Lord Jesus, and in the Spirit of our God."},{"v":12,"t":"“All things are lawful for me,” but not all things are expedient. “All things are lawful for me,” but I will not be brought under the power of anything."},{"v":13,"t":"“Foods for the belly, and the belly for foods,” but God will bring to nothing both it and them. But the body is not for sexual immorality, but for the Lord, and the Lord for the body."},{"v":14,"t":"Now God raised up the Lord, and will also raise us up by his power."},{"v":15,"t":"Don’t you know that your bodies are members of Christ? Shall I then take the members of Christ and make them members of a prostitute? May it never be!"},{"v":16,"t":"Or don’t you know that he who is joined to a prostitute is one body? For, “The two”, he says, “will become one flesh.”"},{"v":17,"t":"But he who is joined to the Lord is one spirit."},{"v":18,"t":"Flee sexual immorality! “Every sin that a man does is outside the body,” but he who commits sexual immorality sins against his own body."},{"v":19,"t":"Or don’t you know that your body is a temple of the Holy Spirit who is in you, whom you have from God? You are not your own,"},{"v":20,"t":"for you were bought with a price. Therefore glorify God in your body and in your spirit, which are God’s."}],"hr":[{"v":1,"t":"Tko bi se od vas u sporu s drugim usudio parničiti se pred nepravednima, a ne pred svetima?"},{"v":2,"t":"Ili zar ne znate da će sveti suditi svijet? Pa ako ćete vi suditi svijet, zar niste vrijedni suditi sitnice?"},{"v":3,"t":"Ne znate li da ćemo suditi anđele, kamo li ne ono svagdanje?"},{"v":4,"t":"A vi, kad imate sporove o svagdanjem, sucima postavljate one do kojih Crkva ništa ne drži!"},{"v":5,"t":"Vama na sramotu govorim. Tako? Zar nema među vama ni jednoga mudra koji bi mogao rasuditi među braćom?"},{"v":6,"t":"Nego brat se s bratom parniči, i to pred nevjernicima?"},{"v":7,"t":"Zapravo, već vam je to nedostatak što se parničite među sobom. Zašto radije ne trpite nepravdu? Zašto se radije ne pustite oplijeniti?"},{"v":8,"t":"Nego vi činite nepravdu i plijenite, i to braću."},{"v":9,"t":"Ili zar ne znate da nepravednici neće baštiniti kraljevstva Božjega? Ne varajte se! Ni bludnici, ni idolopoklonici, ni preljubnici, ni mekoputnici, ni muškoložnici,"},{"v":10,"t":"ni kradljivci, ni lakomci, ni pijanice, ni psovači, ni razbojnici neće baštiniti kraljevstva Božjega."},{"v":11,"t":"To evo, bijahu neki od vas, ali oprali ste se, ali posvetili ste se, ali opravdali ste se u imenu Gospodina našega Isusa Krista i u Duhu Boga našega."},{"v":12,"t":"“Sve mi je dopušteno!” Ali - sve ne koristi. “Sve mi je dopušteno!” Ali - neću da mnome išta vlada."},{"v":13,"t":"“Jela trbuhu, a trbuh jelima; Bog će i jedno i drugo uništiti.” Ali ne tijelo bludnosti, nego Gospodinu, i Gospodin tijelu!"},{"v":14,"t":"Ta Bog koji je Gospodina uskrisio i nas će uskrisiti snagom njegovom."},{"v":15,"t":"Ne znate li da su tijela vaša udovi Kristovi? Hoću li dakle uzeti udove Kristove i učiniti ih udovima bludničinim? Nipošto!"},{"v":16,"t":"Ili zar ne znate: tko uz bludnicu prione, jedno je tijelo? Jer veli se: Bit će njih dvoje jedno tijelo."},{"v":17,"t":"A tko prione uz Gospodina, jedan je duh."},{"v":18,"t":"Bježite od bludnosti! Svaki grijeh koji učini čovjek, izvan tijela je, a bludnik griješi protiv svojega tijela."},{"v":19,"t":"Ili zar ne znate? Tijelo vaše hram je Duha Svetoga koji je u vama, koga imate od Boga, te niste svoji."},{"v":20,"t":"Jer kupljeni ste otkupninom. Proslavite dakle Boga u tijelu svojem!"}]},"7":{"fa":[{"v":1,"t":"اما درباره آنچه به من نوشته بودید: مرد رانیکو آن است که زن را لمس نکند."},{"v":2,"t":"لکن بسبب زنا، هر مرد زوجه خود را بدارد و هر زن شوهر خود را بدارد."},{"v":3,"t":"و شوهر حق زن را ادانماید و همچنین زن حق شوهر را."},{"v":4,"t":"زن بر بدن خود مختار نیست بلکه شوهرش، و همچنین مرد نیز اختیار بدن خود ندارد بلکه زنش،"},{"v":5,"t":"از یکدیگرجدایی مگزینید مگر مدتی به رضای طرفین تابرای روزه و عبادت فارغ باشید؛ و باز با هم پیوندید مبادا شیطان شما را به‌سبب ناپرهیزی شما در تجربه اندازد،"},{"v":6,"t":"لکن این را می‌گویم به طریق اجازه نه به طریق حکم."},{"v":7,"t":"اما می‌خواهم که همه مردم مثل خودم باشند. لکن هرکس نعمتی خاص از خدا دارد، یکی چنین و دیگری چنان."},{"v":8,"t":"لکن به مجردین و بیوه‌زنان می‌گویم که ایشان را نیکو است که مثل من بمانند."},{"v":9,"t":"لکن اگر پرهیزندارند، نکاح بکنند زیرا که نکاح از آتش هوس بهتر است."},{"v":10,"t":"اما منکوحان را حکم می‌کنم و نه من بلکه خداوند که زن از شوهر خود جدا نشود؛"},{"v":11,"t":"و اگر جدا شود، مجرد بماند یا با شوهر خودصلح کند؛ و مرد نیز زن خود را جدا نسازد."},{"v":12,"t":"و دیگران را من می‌گویم نه خداوند که اگرکسی از برادران زنی بی‌ایمان داشته باشد و آن زن راضی باشد که با وی بماند، او را جدا نسازد."},{"v":13,"t":"وزنی که شوهر بی‌ایمان داشته باشد و او راضی باشد که با وی بماند، از شوهر خود جدا نشود."},{"v":14,"t":"زیرا که شوهر بی‌ایمان از زن خود مقدس می‌شود و زن بی‌ایمان از برادر مقدس می‌گردد واگرنه اولاد شما ناپاک می‌بودند، لکن الحال مقدسند."},{"v":15,"t":"اما اگر بی‌ایمان جدایی نماید، بگذارش که بشود زیرا برادر یا خواهر در این صورت مقید نیست و خدا ما را به سلامتی خوانده است."},{"v":16,"t":"زیرا که تو چه دانی‌ای زن که شوهرت را نجات خواهی داد؟ یا چه دانی‌ای مرد که زن خود را نجات خواهی داد؟"},{"v":17,"t":"مگر اینکه به هرطور که خداوند به هرکس قسمت فرموده و به همان حالت که خدا هرکس راخوانده باشد، بدینطور رفتار بکند؛ و همچنین درهمه کلیساها امر می‌کنم."},{"v":18,"t":"اگر کسی در مختونی خوانده شود، نامختون نگردد و اگر کسی درنامختونی خوانده شود، مختون نشود."},{"v":19,"t":"ختنه چیزی نیست و نامختونی هیچ، بلکه نگاه داشتن امرهای خدا."},{"v":20,"t":"هرکس در هر حالتی که خوانده شده باشد، در همان بماند."},{"v":21,"t":"اگر در غلامی خوانده شدی تو را باکی نباشد، بلکه اگر هم می‌توانی آزاد شوی، آن را اولی تر استعمال کن."},{"v":22,"t":"زیرا غلامی که در خداوند خوانده شده باشد، آزاد خداوند است؛ و همچنین شخصی آزاد که خوانده شد، غلام مسیح است."},{"v":23,"t":"به قیمتی خریده شدید، غلام انسان نشوید."},{"v":24,"t":"‌ای برادران هرکس در هرحالتی که خوانده شده باشد، در آن نزد خدا بماند."},{"v":25,"t":"اما درباره باکره‌ها حکمی از خداوند ندارم. لکن چون از خداوند رحمت یافتم که امین باشم، رای می‌دهم."},{"v":26,"t":"پس گمان می‌کنم که بجهت تنگی این زمان، انسان را نیکو آن است که همچنان بماند."},{"v":27,"t":"اگر با زن بسته شدی، جدایی مجوی واگر از زن جدا هستی دیگر زن مخواه."},{"v":28,"t":"لکن هرگاه نکاح کردی، گناه نورزیدی و هرگاه باکره منکوحه گردید، گناه نکرد. ولی چنین در جسم زحمت خواهند کشید، لیکن من بر شما شفقت دارم."},{"v":29,"t":"اما‌ای برادران، این را می‌گویم وقت تنگ است تا بعد از این آنانی که زن دارند مثل بی‌زن باشند"},{"v":30,"t":"و گریانان چون ناگریانان و خوشحالان مثل ناخوشحالان و خریدارن چون غیرمالکان باشند،"},{"v":31,"t":"و استعمال کنندگان این جهان مثل استعمال کنندگان نباشند، زیرا که صورت این جهان درگذر است."},{"v":32,"t":"اما خواهش این دارم که شما بی‌اندیشه باشید. شخص مجرد در امور خداوند می‌اندیشدکه چگونه رضامندی خداوند را بجوید؛"},{"v":33,"t":"وصاحب زن در امور دنیا می‌اندیشد که چگونه زن خود را خوش بسازد."},{"v":34,"t":"در میان زن منکوحه وباکره نیز تفاوتی است، زیرا باکره در امور خداوندمی اندیشد تا هم در تن و هم در روح مقدس باشد؛ اما منکوحه در امور دنیا می‌اندیشد تا شوهر خودرا خوش سازد."},{"v":35,"t":"اما این را برای نفع شمامی گویم نه آنکه دامی بر شما بنهم بلکه نظر به شایستگی و ملازمت خداوند، بی‌تشویش."},{"v":36,"t":"لکن هرگاه کسی گمان برد که با باکره خودناشایستگی می‌کند، اگر به حد بلوغ رسید و ناچاراست از چنین شدن، آنچه خواهد بکند؛ گناهی نیست؛ بگذار که نکاح کنند."},{"v":37,"t":"اما کسی‌که در دل خود پایدار است و احتیاج ندارد بلکه در اراده خود مختار است و در دل خود جازم است که باکره خود را نگاه دارد، نیکو می‌کند."},{"v":38,"t":"پس هم کسی‌که به نکاح دهد، نیکو می‌کند و کسی‌که به نکاح ندهد، نیکوتر می‌نماید."},{"v":39,"t":"زن مادامی که شوهرش زنده است، بسته است. اما هرگاه شوهرش مرد آزاد گردید تا به هرکه بخواهد منکوحه شود، لیکن در خداوندفقط."},{"v":40,"t":"اما بحسب رای من خوشحال تر است، اگر چنین بماند و من نیز گمان می‌برم که روح خدارا دارم."}],"en":[{"v":1,"t":"Now concerning the things about which you wrote to me: it is good for a man not to touch a woman."},{"v":2,"t":"But, because of sexual immoralities, let each man have his own wife, and let each woman have her own husband."},{"v":3,"t":"Let the husband give his wife the affection owed her, and likewise also the wife her husband."},{"v":4,"t":"The wife doesn’t have authority over her own body, but the husband does. Likewise also the husband doesn’t have authority over his own body, but the wife does."},{"v":5,"t":"Don’t deprive one another, unless it is by consent for a season, that you may give yourselves to fasting and prayer, and may be together again, that Satan doesn’t tempt you because of your lack of self-control."},{"v":6,"t":"But this I say by way of concession, not of commandment."},{"v":7,"t":"Yet I wish that all men were like me. However, each man has his own gift from God, one of this kind, and another of that kind."},{"v":8,"t":"But I say to the unmarried and to widows, it is good for them if they remain even as I am."},{"v":9,"t":"But if they don’t have self-control, let them marry. For it’s better to marry than to burn with passion."},{"v":10,"t":"But to the married I command—not I, but the Lord—that the wife not leave her husband"},{"v":11,"t":"(but if she departs, let her remain unmarried, or else be reconciled to her husband), and that the husband not leave his wife."},{"v":12,"t":"But to the rest I—not the Lord—say, if any brother has an unbelieving wife, and she is content to live with him, let him not leave her."},{"v":13,"t":"The woman who has an unbelieving husband, and he is content to live with her, let her not leave her husband."},{"v":14,"t":"For the unbelieving husband is sanctified in the wife, and the unbelieving wife is sanctified in the husband. Otherwise your children would be unclean, but now they are holy."},{"v":15,"t":"Yet if the unbeliever departs, let there be separation. The brother or the sister is not under bondage in such cases, but God has called us in peace."},{"v":16,"t":"For how do you know, wife, whether you will save your husband? Or how do you know, husband, whether you will save your wife?"},{"v":17,"t":"Only, as the Lord has distributed to each man, as God has called each, so let him walk. So I command in all the assemblies."},{"v":18,"t":"Was anyone called having been circumcised? Let him not become uncircumcised. Has anyone been called in uncircumcision? Let him not be circumcised."},{"v":19,"t":"Circumcision is nothing, and uncircumcision is nothing, but what matters is keeping God’s commandments."},{"v":20,"t":"Let each man stay in that calling in which he was called."},{"v":21,"t":"Were you called being a bondservant? Don’t let that bother you, but if you get an opportunity to become free, use it."},{"v":22,"t":"For he who was called in the Lord being a bondservant is the Lord’s free man. Likewise he who was called being free is Christ’s bondservant."},{"v":23,"t":"You were bought with a price. Don’t become bondservants of men."},{"v":24,"t":"Brothers, let each man, in whatever condition he was called, stay in that condition with God."},{"v":25,"t":"Now concerning virgins, I have no commandment from the Lord, but I give my judgment as one who has obtained mercy from the Lord to be trustworthy."},{"v":26,"t":"Therefore I think that because of the distress that is on us, it’s good for a man to remain as he is."},{"v":27,"t":"Are you bound to a wife? Don’t seek to be freed. Are you free from a wife? Don’t seek a wife."},{"v":28,"t":"But if you marry, you have not sinned. If a virgin marries, she has not sinned. Yet such will have oppression in the flesh, and I want to spare you."},{"v":29,"t":"But I say this, brothers: the time is short. From now on, both those who have wives may be as though they had none;"},{"v":30,"t":"and those who weep, as though they didn’t weep; and those who rejoice, as though they didn’t rejoice; and those who buy, as though they didn’t possess;"},{"v":31,"t":"and those who use the world, as not using it to the fullest. For the mode of this world passes away."},{"v":32,"t":"But I desire to have you to be free from cares. He who is unmarried is concerned for the things of the Lord, how he may please the Lord;"},{"v":33,"t":"but he who is married is concerned about the things of the world, how he may please his wife."},{"v":34,"t":"There is also a difference between a wife and a virgin. The unmarried woman cares about the things of the Lord, that she may be holy both in body and in spirit. But she who is married cares about the things of the world—how she may please her husband."},{"v":35,"t":"This I say for your own benefit, not that I may ensnare you, but for that which is appropriate, and that you may attend to the Lord without distraction."},{"v":36,"t":"But if any man thinks that he is behaving inappropriately toward his virgin, if she is past the flower of her age, and if need so requires, let him do what he desires. He doesn’t sin. Let them marry."},{"v":37,"t":"But he who stands steadfast in his heart, having no urgency, but has power over his own will, and has determined in his own heart to keep his own virgin, does well."},{"v":38,"t":"So then both he who gives his own virgin in marriage does well, and he who doesn’t give her in marriage does better."},{"v":39,"t":"A wife is bound by law for as long as her husband lives; but if the husband is dead, she is free to be married to whomever she desires, only in the Lord."},{"v":40,"t":"But she is happier if she stays as she is, in my judgment, and I think that I also have God’s Spirit."}],"hr":[{"v":1,"t":"Sada o onome što ste mi pisali. Dobro je čovjeku ne dotaći ženu."},{"v":2,"t":"Ipak, zbog bludnosti, neka svaki ima svoju ženu i svaka neka ima svoga muža."},{"v":3,"t":"Muž neka vrši dužnost prema ženi, a tako i žena prema mužu."},{"v":4,"t":"Žena nije gospodar svoga tijela, nego muž, a tako ni muž nije gospodar svoga tijela, nego žena."},{"v":5,"t":"Ne uskraćujte se jedno drugome, osim po dogovoru, povremeno, da se posvetite molitvi pa se opet združite da vas Sotona ne bi napastovao zbog vaše neizdržljivosti."},{"v":6,"t":"Ali to velim kao dopuštenje, ne kao zapovijed."},{"v":7,"t":"A htio bih da svi ljudi budu kao i ja; ali svatko ima svoj dar od Boga, ovaj ovako, onaj onako."},{"v":8,"t":"Neoženjenima pak i udovicama velim: dobro im je ako ostanu kao i ja."},{"v":9,"t":"Ako li se ne mogu uzdržati, neka se žene, udaju. Jer bolje je ženiti se negoli izgarati."},{"v":10,"t":"A oženjenima zapovijedam, ne ja, nego Gospodin: žena neka se od muža ne rastavlja -"},{"v":11,"t":"ako se ipak rastavi, neka ostane neudana ili neka se s mužem pomiri - i muž neka ne otpušta žene."},{"v":12,"t":"Ostalima pak velim - ja, ne Gospodin: ima li koji brat ženu nevjernicu i ona privoli stanovati s njime, neka je ne otpušta."},{"v":13,"t":"I žena koja ima muža nevjernika te on privoli stanovati s njome, neka ne otpušta muža."},{"v":14,"t":"Ta muž nevjernik posvećen je ženom i žena nevjernica posvećena je bratom. Inače bi djeca vaša bila nečista, a ovako - sveta su."},{"v":15,"t":"Ako li se nevjernik hoće rastaviti, neka se rastavi; brat ili sestra u takvim prilikama nisu vezani: ta na mir nas je pozvao Bog."},{"v":16,"t":"Jer što znaš, ženo, hoćeš li spasiti muža? Ili što znaš, mužu, hoćeš li spasiti ženu?"},{"v":17,"t":"U drugome svatko neka živi kako mu je Gospodin dodijelio, kako ga je Bog pozvao. Tako određujem po svim crkvama."},{"v":18,"t":"Je li tko pozvan kao obrezan, neka ne prepravlja obrezanja. Ako je pozvan kao neobrezan, neka se ne obrezuje."},{"v":19,"t":"Obrezanje nije ništa i neobrezanje nije ništa, nego - držanje Božjih zapovijedi."},{"v":20,"t":"Svatko neka ostane u onom zvanju u koje je pozvan."},{"v":21,"t":"Jesi li pozvan kao rob? Ne brini! Nego, ako i možeš postati slobodan, radije se okoristi."},{"v":22,"t":"Jer tko je u Gospodinu pozvan kao rob, slobodnjak je Gospodnji. Tako i tko je pozvan kao slobodnjak, rob je Kristov."},{"v":23,"t":"Otkupninom ste kupljeni: ne budite robovi ljudima."},{"v":24,"t":"Svatko u čemu je pozvan, braćo, u tome neka i ostane pred Bogom."},{"v":25,"t":"O djevicama nemam zapovijedi, nego dajem savjet kao čovjek po milosrđu Gospodnjem vrijedan povjerenja."},{"v":26,"t":"Smatram dakle: dobro je to zbog sadašnje nevolje, dobro je čovjeku tako biti."},{"v":27,"t":"Jesi li vezan za ženu? Ne traži rastave. Jesi li slobodan od žene? Ne traži žene."},{"v":28,"t":"Ali ako se i oženiš, nisi sagriješio; i djevica ako se uda, nije sagriješila. Ali takvi će imati tjelesnu nevolju, a ja bih vas rado poštedio."},{"v":29,"t":"Ovo hoću reći, braćo: Vrijeme je kratko. Odsele i koji imaju žene, neka budu kao da ih nemaju;"},{"v":30,"t":"i koji plaču, kao da ne plaču; i koji se vesele, kao da se ne vesele; i koji kupuju, kao da ne posjeduju;"},{"v":31,"t":"i koji uživaju ovaj svijet, kao da ga ne uživaju, jer - prolazi obličje ovoga svijeta."},{"v":32,"t":"A rado bih da budete bezbrižni. Neoženjen se brine za Gospodnje, kako da ugodi Gospodinu."},{"v":33,"t":"A oženjen se brine za svjetovno, kako da ugodi ženi,"},{"v":34,"t":"pa je razdijeljen. I žena neudana i djevica brine se za Gospodnje, da bude sveta i tijelom i duhom; a udana se brine za svjetovno, kako da ugodi mužu."},{"v":35,"t":"Ovo pak govorim vama na korist, ne da vam postavim zamku, nego da primjerno i nesmetano budete privrženi Gospodinu."},{"v":36,"t":"Misli li tko da je nepriličan prema svojoj djevici kad je preživotan i s njome mora biti, neka čini što je nakanio, ne griješi: neka se uzmu."},{"v":37,"t":"Tko je pak nepokolebljivo stalan u srcu te nema potrebe, a u vlasti mu je volja pa to odluči u svom srcu - čuvati svoju djevicu - dobro čini."},{"v":38,"t":"Tako, tko se oženi svojom djevicom, dobro čini, a tko se ne oženi, bolje čini."},{"v":39,"t":"Žena je vezana dokle živi muž njezin. Umre li muž, slobodna je: neka se uda za koga hoće, samo u Gospodinu."},{"v":40,"t":"Bit će ipak blaženija ostane li onako, po mojem savjetu. A mislim da i ja imam Duha Božjega."}]},"8":{"fa":[{"v":1,"t":"اما درباره قربانی های بتها: می‌دانیم که همه علم داریم. علم باعث تکبر است، لکن محبت بنا می‌کند."},{"v":2,"t":"اگر کسی گمان برد که چیزی می‌داند، هنوز هیچ نمی داند، بطوری که بایددانست."},{"v":3,"t":"اما اگر کسی خدا را محبت نماید، نزد اومعروف می‌باشد."},{"v":4,"t":"پس درباره خوردن قربانی های بتها، می‌دانیم که بت در جهان چیزی نیست و اینکه خدایی دیگر جز یکی نیست."},{"v":5,"t":"زیرا هرچند هستند که به خدایان خوانده می‌شوند، چه در آسمان و چه درزمین، چنانکه خدایان بسیار و خداوندان بسیارمی باشند،"},{"v":6,"t":"لکن ما را یک خداست یعنی پدر که همه‌چیز از اوست و ما برای او هستیم، و یک خداوند یعنی عیسی مسیح که همه‌چیز از اوست و ما از او هستیم."},{"v":7,"t":"ولی همه را این معرفت نیست، زیرا بعضی تابه حال به اعتقاد اینکه بت هست، آن را چون قربانی بت می‌خورند و ضمیر ایشان چون ضعیف است نجس می‌شود."},{"v":8,"t":"اما خوراک، ما رامقبول خدا نمی سازد زیرا که نه به خوردن بهتریم و نه به ناخوردن بدتر."},{"v":9,"t":"لکن احتیاط کنید مبادااختیار شما باعث لغزش ضعفا گردد."},{"v":10,"t":"زیرا اگرکسی تو را که صاحب علم هستی بیند که در بتکده نشسته‌ای، آیا ضمیر آن کس که ضعیف است به خوردن قربانی های بتها بنا نمی شود؟"},{"v":11,"t":"و از علم تو آن برادر ضعیف که مسیح برای او مرد هلاک خواهد شد."},{"v":12,"t":"و همچنین چون به برادران گناه ورزیدید و ضمایر ضعیفشان را صدمه رسانیدید، همانا به مسیح خطا نمودید."},{"v":13,"t":"بنابراین، اگرخوراک باعث لغزش برادر من باشد، تا به ابدگوشت نخواهم خورد تا برادر خود را لغزش ندهم."}],"en":[{"v":1,"t":"Now concerning things sacrificed to idols: We know that we all have knowledge. Knowledge puffs up, but love builds up."},{"v":2,"t":"But if anyone thinks that he knows anything, he doesn’t yet know as he ought to know."},{"v":3,"t":"But anyone who loves God is known by him."},{"v":4,"t":"Therefore concerning the eating of things sacrificed to idols, we know that no idol is anything in the world, and that there is no other God but one."},{"v":5,"t":"For though there are things that are called “gods”, whether in the heavens or on earth—as there are many “gods” and many “lords”—"},{"v":6,"t":"yet to us there is one God, the Father, of whom are all things, and we for him; and one Lord, Jesus Christ, through whom are all things, and we live through him."},{"v":7,"t":"However, that knowledge isn’t in all men. But some, with consciousness of an idol until now, eat as of a thing sacrificed to an idol, and their conscience, being weak, is defiled."},{"v":8,"t":"But food will not commend us to God. For neither, if we don’t eat are we the worse, nor if we eat are we the better."},{"v":9,"t":"But be careful that by no means does this liberty of yours become a stumbling block to the weak."},{"v":10,"t":"For if a man sees you who have knowledge sitting in an idol’s temple, won’t his conscience, if he is weak, be emboldened to eat things sacrificed to idols?"},{"v":11,"t":"And through your knowledge, he who is weak perishes, the brother for whose sake Christ died."},{"v":12,"t":"Thus, sinning against the brothers, and wounding their conscience when it is weak, you sin against Christ."},{"v":13,"t":"Therefore, if food causes my brother to stumble, I will eat no meat forever more, that I don’t cause my brother to stumble."}],"hr":[{"v":1,"t":"U pogledu mesa žrtvovana idolima, znamo, svi posjedujemo znanje. Ali znanje nadima, a ljubav izgrađuje."},{"v":2,"t":"Ako tko misli da što zna, još ne zna kako treba znati."},{"v":3,"t":"A ljubi li tko Boga, Bog ga poznaje."},{"v":4,"t":"Dakle, u pogledu blagovanja mesa žrtvovana idolima, znamo: nema idola na svijetu i nema Boga do Jednoga."},{"v":5,"t":"Jer sve kad bi i bilo nazovibogova ili na nebu ili na zemlji - kao što ima mnogo “bogova” i mnogo “gospodara”! -"},{"v":6,"t":"nama je jedan Bog, Otac, od koga je sve, a mi za njega; i jedan Gospodin, Isus Krist, po kome je sve, i mi po njemu."},{"v":7,"t":"Ali nemaju svi toga znanja. Neki, navikli na idole, još jedu meso kao idolima žrtvovano i njihova se savjest kalja jer je nejaka."},{"v":8,"t":"A k Bogu nas ne privodi jelo. Niti što gubimo ako ne jedemo; niti što dobivamo ako jedemo."},{"v":9,"t":"A pazite da ne bi možda ta vaša sloboda bila spoticaj nejakima."},{"v":10,"t":"Jer vidi li tko tebe koji imaš znanje za stolom u hramu idolskomu, neće li se njegova savjest, jer je nejaka, “izgraditi” da jede žrtvovano idolima?"},{"v":11,"t":"I s tvoga znanja propada nejaki, brat za kojega je Krist umro."},{"v":12,"t":"Tako griješeći protiv braće i ranjavajući njihovu nejaku savjest, protiv Krista griješite."},{"v":13,"t":"Zato ako jelo sablažnjava brata moga, ne, neću jesti mesa dovijeka da brata svoga ne sablaznim."}]},"9":{"fa":[{"v":1,"t":"آیا رسول نیستم؟ آیا آزاد نیستم؟ آیا عیسی مسیح خداوند ما را ندیدم؟ آیا شماعمل من در خداوند نیستید؟"},{"v":2,"t":"هرگاه دیگران رارسول نباشم، البته شما را هستم زیرا که مهررسالت من در خداوند شما هستید."},{"v":3,"t":"حجت من بجهت آنانی که مرا امتحان می‌کنند این است"},{"v":4,"t":"که آیا اختیار خوردن و آشامیدن نداریم؟"},{"v":5,"t":"آیااختیار نداریم که خواهر دینی را به زنی گرفته، همراه خود ببریم، مثل سایر رسولان و برادران خداوند و کیفا؟"},{"v":6,"t":"یا من و برنابا به تنهایی مختارنیستیم که کار نکنیم؟"},{"v":7,"t":"کیست که هرگز از خرجی خود جنگ کند؟ یا کیست که تاکستانی غرس نموده، از میوه‌اش نخورد؟ یا کیست که گله‌ای بچراند و از شیر گله ننوشد؟"},{"v":8,"t":"آیا این را بطور انسان می‌گویم یاشریعت نیز این را نمی گوید؟"},{"v":9,"t":"زیرا که در تورات موسی مکتوب است که «گاو را هنگامی که خرمن را خرد می‌کند، دهان مبند». آیا خدا در فکر گاوان می‌باشد؟"},{"v":10,"t":"آیا محض خاطر ما این رانمی گوید؟ بلی برای ما مکتوب است که شخم کننده می‌باید به امید، شخم نماید و خردکننده خرمن در امید یافتن قسمت خود باشد."},{"v":11,"t":"چون ما روحانیها را برای شما کاشتیم، آیا امربزرگی است که ما جسمانیهای شما را درو کنیم؟"},{"v":12,"t":"اگر دیگران در این اختیار بر شما شریکند آیانه ماه بیشتر؟ لیکن این اختیار را استعمال نکردیم، بلکه هرچیز را متحمل می‌شویم، مبادا انجیل مسیح را تعویق اندازیم."},{"v":13,"t":"آیا نمی دانید که هرکه در امور مقدس مشغول باشد، از هیکل می‌خورد و هرکه خدمت مذبح کند، از مذبح نصیبی می‌دارد."},{"v":14,"t":"و همچنین خداوند فرمود که «هرکه به انجیل اعلام نماید، ازانجیل معیشت یابد»."},{"v":15,"t":"لیکن من هیچیک از اینهارا استعمال نکردم و این را به این قصد ننوشتم تا بامن چنین شود، زیرا که مرا مردن بهتر است از آنکه کسی فخر مرا باطل گرداند."},{"v":16,"t":"زیرا هرگاه بشارت دهم، مرا فخر نیست چونکه مرا ضرورت افتاده است، بلکه وای بر من اگر بشارت ندهم."},{"v":17,"t":"زیراهرگاه این را طوع کنم اجرت دارم، لکن اگر کره باشد وکالتی به من سپرده شد."},{"v":18,"t":"در این صورت، مرا چه اجرت است تا آنکه چون بشارت می‌دهم، انجیل مسیح را بی‌خرج سازم و اختیار خود را درانجیل استعمال نکنم؟"},{"v":19,"t":"زیرا با اینکه از همه کسی آزاد بودم، خودرا غلام همه گردانیدم تا بسیاری را سود برم."},{"v":20,"t":"ویهود را چون یهود گشتم تا یهود را سود برم واهل شریعت را مثل اهل شریعت تا اهل شریعت را سود برم؛"},{"v":21,"t":"و بی‌شریعتان را چون بی‌شریعتان شدم، هرچند نزد خدا بی‌شریعت نیستم، بلکه شریعت مسیح در من است، تا بی‌شریعتان را سودبرم؛"},{"v":22,"t":"ضعفا را ضعیف شدم تا ضعفا را سود برم؛ همه کس را همه‌چیز گردیدم تا به هرنوعی بعضی را برهانم."},{"v":23,"t":"اما همه کار را بجهت انجیل می‌کنم تا در آن شریک گردم."},{"v":24,"t":"آیا نمی دانید آنانی که در میدان می‌دوند، همه می‌دوند لکن یک نفر انعام را می‌برد. به اینطور شما بدوید تا به‌کمال ببرید."},{"v":25,"t":"و هرکه ورزش کند در هرچیز ریاضت می‌کشد؛ اما ایشان تا تاج فانی را بیابند لکن ما تاج غیرفانی را."},{"v":26,"t":"پس من چنین می‌دوم، نه چون کسی‌که شک دارد؛ ومشت می‌زنم نه آنکه هوا را بزنم."},{"v":27,"t":"بلکه تن خودرا زبون می‌سازم و آن را در بندگی می‌دارم، مباداچون دیگران را وعظ نمودم، خود محروم شوم."}],"en":[{"v":1,"t":"Am I not free? Am I not an apostle? Haven’t I seen Jesus Christ, our Lord? Aren’t you my work in the Lord?"},{"v":2,"t":"If to others I am not an apostle, yet at least I am to you; for you are the seal of my apostleship in the Lord."},{"v":3,"t":"My defense to those who examine me is this:"},{"v":4,"t":"Have we no right to eat and to drink?"},{"v":5,"t":"Have we no right to take along a wife who is a believer, even as the rest of the apostles, and the brothers of the Lord, and Cephas?"},{"v":6,"t":"Or have only Barnabas and I no right to not work?"},{"v":7,"t":"What soldier ever serves at his own expense? Who plants a vineyard, and doesn’t eat of its fruit? Or who feeds a flock, and doesn’t drink from the flock’s milk?"},{"v":8,"t":"Do I speak these things according to the ways of men? Or doesn’t the law also say the same thing?"},{"v":9,"t":"For it is written in the law of Moses, “You shall not muzzle an ox while it treads out the grain.” Is it for the oxen that God cares,"},{"v":10,"t":"or does he say it assuredly for our sake? Yes, it was written for our sake, because he who plows ought to plow in hope, and he who threshes in hope should partake of his hope."},{"v":11,"t":"If we sowed to you spiritual things, is it a great thing if we reap your fleshly things?"},{"v":12,"t":"If others partake of this right over you, don’t we yet more? Nevertheless we didn’t use this right, but we bear all things, that we may cause no hindrance to the Good News of Christ."},{"v":13,"t":"Don’t you know that those who serve around sacred things eat from the things of the temple, and those who wait on the altar have their portion with the altar?"},{"v":14,"t":"Even so the Lord ordained that those who proclaim the Good News should live from the Good News."},{"v":15,"t":"But I have used none of these things, and I don’t write these things that it may be done so in my case; for I would rather die, than that anyone should make my boasting void."},{"v":16,"t":"For if I preach the Good News, I have nothing to boast about, for necessity is laid on me; but woe is to me if I don’t preach the Good News."},{"v":17,"t":"For if I do this of my own will, I have a reward. But if not of my own will, I have a stewardship entrusted to me."},{"v":18,"t":"What then is my reward? That when I preach the Good News, I may present the Good News of Christ without charge, so as not to abuse my authority in the Good News."},{"v":19,"t":"For though I was free from all, I brought myself under bondage to all, that I might gain the more."},{"v":20,"t":"To the Jews I became as a Jew, that I might gain Jews; to those who are under the law, as under the law, that I might gain those who are under the law;"},{"v":21,"t":"to those who are without law, as without law (not being without law toward God, but under law toward Christ), that I might win those who are without law."},{"v":22,"t":"To the weak I became as weak, that I might gain the weak. I have become all things to all men, that I may by all means save some."},{"v":23,"t":"Now I do this for the sake of the Good News, that I may be a joint partaker of it."},{"v":24,"t":"Don’t you know that those who run in a race all run, but one receives the prize? Run like that, so that you may win."},{"v":25,"t":"Every man who strives in the games exercises self-control in all things. Now they do it to receive a corruptible crown, but we an incorruptible."},{"v":26,"t":"I therefore run like that, not aimlessly. I fight like that, not beating the air,"},{"v":27,"t":"but I beat my body and bring it into submission, lest by any means, after I have preached to others, I myself should be disqualified."}],"hr":[{"v":1,"t":"Nisam li ja slobodan? Nisam li apostol? Nisam li vidio Isusa, Gospodina našega? Niste li vi djelo moje u Gospodinu?"},{"v":2,"t":"Ako drugima nisam apostol, vama svakako jesam. Ta vi ste pečat mojega apostolstva u Gospodinu."},{"v":3,"t":"Moj odgovor mojim tužiteljima jest ovo:"},{"v":4,"t":"Zar nemamo prava jesti i piti?"},{"v":5,"t":"Zar nemamo prava ženu vjernicu voditi sa sobom kao i drugi apostoli i braća Gospodnja i Kefa?"},{"v":6,"t":"Ili samo ja i Barnaba nemamo prava ne raditi?"},{"v":7,"t":"Tko ikada vojuje o svojem trošku? Tko sadi vinograd pa roda njegova ne jede? Ili tko pase stado pa od mlijeka stada ne jede?"},{"v":8,"t":"Zar to govorim po ljudsku? Ne kaže li to i Zakon?"},{"v":9,"t":"Jer u Mojsijevu zakonu piše: Ne zavezuj usta volu koji vrši! Zar je Bogu do volova?"},{"v":10,"t":"Ne govori li on baš radi nas? Doista, radi nas je napisano, jer tko ore, u nadi treba da ore; i tko vrši, u nadi da će dobiti dio."},{"v":11,"t":"Ako smo mi vama sijali dobra duhovna, veliko li je nešto ako vam požanjemo tjelesna?"},{"v":12,"t":"Ako drugi sudjeluju u vašim dobrima, zašto ne bismo mi mogli još većma. Ali nismo se poslužili tim pravom, nego sve teglimo da ne bismo postavili kakvu zapreku evanđelju Kristovu?"},{"v":13,"t":"Ne znate li: koji obavljaju svetinje, od svetišta se hrane; i koji žrtveniku služe, sa žrtvenikom dijele?"},{"v":14,"t":"Tako je i Gospodin onima koji evanđelje navješćuju odredio od evanđelja živjeti."},{"v":15,"t":"No ja se ničim od toga nisam poslužio. A i ne napisah toga da bi se tako postupilo prema meni. Radije umrijeti, nego... Te mi slave nitko neće oduzeti!"},{"v":16,"t":"Jer što navješćujem evanđelje, nije mi na hvalu, ta dužnost mi je. Doista, jao meni ako evanđelja ne navješćujem."},{"v":17,"t":"Jer ako to činim iz vlastite pobude, ide me plaća; ako li ne iz vlastite pobude - služba je to koja mi je povjerena."},{"v":18,"t":"Koja mi je dakle plaća? Da propovijedajući pružam evanđelje besplatno ne služeći se svojim pravom u evanđelju."},{"v":19,"t":"Jer premda slobodan od sviju, sam sebe svima učinih slugom da ih što više steknem."},{"v":20,"t":"Bijah Židovima Židov da Židove steknem; onima pod Zakonom, kao da sam pod Zakonom - premda ja nisam pod Zakonom - da one pod Zakonom steknem;"},{"v":21,"t":"onima bez Zakona, kao da sam bez zakona - premda nisam bez Božjega zakona, nego u Kristovu zakonu - da steknem one bez Zakona;"},{"v":22,"t":"bijah nejakima nejak da nejake steknem. Svima bijah sve da pošto-poto neke spasim."},{"v":23,"t":"A sve činim poradi evanđelja da bih i ja bio suzajedničar u njemu."},{"v":24,"t":"Ne znate li: trkači u trkalištu svi doduše trče, ali jedan prima nagradu? Tako trčite da dobijete."},{"v":25,"t":"Svaki natjecatelj sve moguće izdržava; oni da dobiju raspadljiv vijenac, mi neraspadljiv."},{"v":26,"t":"Ja dakle tako trčim - ne kao besciljno, tako udaram šakom - ne kao da mlatim vjetar,"},{"v":27,"t":"nego krotim svoje tijelo i zarobljavam da sam ne budem isključen pošto sam drugima propovijedao."}]},"10":{"fa":[{"v":1,"t":"زیرا‌ای برادران نمی خواهم شما بی خبر باشید از اینکه پدران ما همه زیرابر بودند و همه از دریا عبور نمودند"},{"v":2,"t":"و همه به موسی تعمید یافتند، در ابر و در دریا؛"},{"v":3,"t":"و همه همان خوراک روحانی را خوردند"},{"v":4,"t":"و همه همان شرب روحانی را نوشیدند، زیرا که می‌آشامیدنداز صخره روحانی که از عقب ایشان می‌آمد و آن صخره مسیح بود."},{"v":5,"t":"لیکن از اکثر ایشان خداراضی نبود، زیرا که در بیابان انداخته شدند."},{"v":6,"t":"و این امور نمونه‌ها برای ما شد تا ماخواهشمند بدی نباشیم، چنانکه ایشان بودند؛"},{"v":7,"t":"ونه بت‌پرست شوید، مثل بعضی از ایشان، چنانکه مکتوب است: «قوم به اکل و شرب نشستند وبرای لهو و لعب برپا شدند.»"},{"v":8,"t":"و نه زنا کنیم چنانکه بعضی از ایشان کردند و در یک روزبیست و سه هزار نفر هلاک گشتند."},{"v":9,"t":"و نه مسیح راتجربه کنیم، چنانکه بعضی از ایشان کردند و ازمارها هلاک گردیدند."},{"v":10,"t":"و نه همهمه کنید، چنانکه بعضی از ایشان کردند و هلاک کننده ایشان را هلاک کرد."},{"v":11,"t":"و این همه بطور مثل بدیشان واقع شد وبرای تنبیه ما مکتوب گردید که اواخر عالم به ما رسیده است."},{"v":12,"t":"پس آنکه گمان برد که قایم است، باخبر باشد که نیفتد."},{"v":13,"t":"هیچ تجربه جز آنکه مناسب بشر باشد، شما را فرو نگرفت. اما خداامین است که نمی گذارد شما فوق طاقت خودآزموده شوید، بلکه باتجربه مفری نیز می‌سازد تایارای تحمل آن را داشته باشید."},{"v":14,"t":"لهذا‌ای عزیزان من از بت‌پرستی بگریزید."},{"v":15,"t":"به خردمندان سخن می‌گویم: خود حکم کنیدبرآنچه می‌گویم."},{"v":16,"t":"پیاله برکت که آن را تبرک می‌خوانیم، آیا شراکت در خون مسیح نیست؟ ونانی را که پاره می‌کنیم، آیا شراکت در بدن مسیح نی؟"},{"v":17,"t":"زیرا ما که بسیاریم، یک نان و یکتن می‌باشیم چونکه همه از یک نان قسمت می‌یابیم."},{"v":18,"t":"اسرائیل جسمانی را ملاحظه کنید! آیاخورندگان قربانی‌ها شریک قربانگاه نیستند؟"},{"v":19,"t":"پس چه گویم؟ آیا بت چیزی می‌باشد؟ یا که قربانی بت چیزی است؟"},{"v":20,"t":"نی! بلکه آنچه امت هاقربانی می‌کنند، برای دیوها می‌گذرانند نه برای خدا؛ و نمی خواهم شما شریک دیوها باشید."},{"v":21,"t":"محال است که هم از پیاله خداوند و هم از پیاله دیوها بنوشید؛ و هم از مایده خداوند و هم ازمایده دیوها نمی توانید قسمت برد."},{"v":22,"t":"آیاخداوند را به غیرت می‌آوریم یا از او تواناترمی باشیم؟"},{"v":23,"t":"همه‌چیز جایز است، لیکن همه مفیدنیست؛ همه رواست، لیکن همه بنا نمی کند."},{"v":24,"t":"هرکس نفع خود را نجوید، بلکه نفع دیگری را."},{"v":25,"t":"هرآنچه را در قصابخانه می‌فروشند، بخوریدو هیچ مپرسید به‌خاطر ضمیر."},{"v":26,"t":"زیرا که جهان و پری آن از آن خداوند است."},{"v":27,"t":"هرگاه کسی ازبی ایمانان از شما وعده خواهد و می‌خواهیدبروید، آنچه نزد شما گذارند بخورید و هیچ مپرسید بجهت ضمیر."},{"v":28,"t":"اما اگر کسی به شماگوید «این قربانی بت است»، مخورید به‌خاطر آن کس که خبر داد و بجهت ضمیر، زیرا که جهان وپری آن از آن خداوند است."},{"v":29,"t":"اما ضمیرمی گویم نه از خودت بلکه ضمیر آن دیگر؛ زیراچرا ضمیر دیگری بر آزادی من حکم کند؟"},{"v":30,"t":"واگر من به شکر بخورم، چرا بر من افترا زنند به‌سبب آن چیزی که من برای آن شکر می‌کنم؟"},{"v":31,"t":"پس خواه بخورید، خواه بنوشید، خواه هرچه کنید، همه را برای جلال خدا بکنید."},{"v":32,"t":"یهودیان و یونانیان و کلیسای خدا را لغزش مدهید."},{"v":33,"t":"چنانکه من نیز در هرکاری همه را خوش می‌سازم و نفع خود را طالب نیستم، بلکه نفع بسیاری را تا نجات یابند."}],"en":[{"v":1,"t":"Now I would not have you ignorant, brothers, that our fathers were all under the cloud, and all passed through the sea;"},{"v":2,"t":"and were all baptized into Moses in the cloud and in the sea;"},{"v":3,"t":"and all ate the same spiritual food;"},{"v":4,"t":"and all drank the same spiritual drink. For they drank of a spiritual rock that followed them, and the rock was Christ."},{"v":5,"t":"However with most of them, God was not well pleased, for they were overthrown in the wilderness."},{"v":6,"t":"Now these things were our examples, to the intent we should not lust after evil things as they also lusted."},{"v":7,"t":"Don’t be idolaters, as some of them were. As it is written, “The people sat down to eat and drink, and rose up to play.”"},{"v":8,"t":"Let’s not commit sexual immorality, as some of them committed, and in one day twenty-three thousand fell."},{"v":9,"t":"Let’s not test Christ, as some of them tested, and perished by the serpents."},{"v":10,"t":"Don’t grumble, as some of them also grumbled, and perished by the destroyer."},{"v":11,"t":"Now all these things happened to them by way of example, and they were written for our admonition, on whom the ends of the ages have come."},{"v":12,"t":"Therefore let him who thinks he stands be careful that he doesn’t fall."},{"v":13,"t":"No temptation has taken you except what is common to man. God is faithful, who will not allow you to be tempted above what you are able, but will with the temptation also make the way of escape, that you may be able to endure it."},{"v":14,"t":"Therefore, my beloved, flee from idolatry."},{"v":15,"t":"I speak as to wise men. Judge what I say."},{"v":16,"t":"The cup of blessing which we bless, isn’t it a sharing of the blood of Christ? The bread which we break, isn’t it a sharing of the body of Christ?"},{"v":17,"t":"Because there is one loaf of bread, we, who are many, are one body; for we all partake of the one loaf of bread."},{"v":18,"t":"Consider Israel according to the flesh. Don’t those who eat the sacrifices participate in the altar?"},{"v":19,"t":"What am I saying then? That a thing sacrificed to idols is anything, or that an idol is anything?"},{"v":20,"t":"But I say that the things which the Gentiles sacrifice, they sacrifice to demons and not to God, and I don’t desire that you would have fellowship with demons."},{"v":21,"t":"You can’t both drink the cup of the Lord and the cup of demons. You can’t both partake of the table of the Lord and of the table of demons."},{"v":22,"t":"Or do we provoke the Lord to jealousy? Are we stronger than he?"},{"v":23,"t":"“All things are lawful for me,” but not all things are profitable. “All things are lawful for me,” but not all things build up."},{"v":24,"t":"Let no one seek his own, but each one his neighbor’s good."},{"v":25,"t":"Whatever is sold in the butcher shop, eat, asking no question for the sake of conscience,"},{"v":26,"t":"for “the earth is the Lord’s, and its fullness.”"},{"v":27,"t":"But if one of those who don’t believe invites you to a meal, and you are inclined to go, eat whatever is set before you, asking no questions for the sake of conscience."},{"v":28,"t":"But if anyone says to you, “This was offered to idols,” don’t eat it for the sake of the one who told you, and for the sake of conscience. For “the earth is the Lord’s, with all its fullness.”"},{"v":29,"t":"Conscience, I say, not your own, but the other’s conscience. For why is my liberty judged by another conscience?"},{"v":30,"t":"If I partake with thankfulness, why am I denounced for something I give thanks for?"},{"v":31,"t":"Whether therefore you eat or drink, or whatever you do, do all to the glory of God."},{"v":32,"t":"Give no occasion for stumbling, whether to Jews, to Greeks, or to the assembly of God;"},{"v":33,"t":"even as I also please all men in all things, not seeking my own profit, but the profit of the many, that they may be saved."}],"hr":[{"v":1,"t":"Jer ne bih, braćo, htio da budete u neznanju: oci naši svi bijahu pod oblakom, i svi prijeđoše kroz more,"},{"v":2,"t":"i svi su se na Mojsija krstili u oblaku i u moru,"},{"v":3,"t":"i svi su isto duhovno jelo jeli,"},{"v":4,"t":"i svi su isto duhovno piće pili. A pili su iz duhovne stijene koja ih je pratila; stijena bijaše Krist."},{"v":5,"t":"Ali većina njih nije bila po volji Bogu: ta poubijani su po pustinji."},{"v":6,"t":"To bijahu pralikovi naši: da ne žudimo za zlima kao što su žudjeli oni."},{"v":7,"t":"I ne budite idolopoklonici kao neki od njih, kako je pisano: Posjeda narod da jede i pije pa ustadoše da igraju."},{"v":8,"t":"I ne podajimo se bludu kao što se neki od njih bludu podaše i padoše u jednom danu dvadeset i tri tisuće."},{"v":9,"t":"I ne iskušavajmo Gospodina kao što su ga neki od njih iskušavali te od zmija izginuli."},{"v":10,"t":"I ne mrmljajte kao što neki od njih mrmljahu te izgiboše od Zatornika."},{"v":11,"t":"Sve se to, kao pralik, događalo njima, a napisano je za upozorenje nama, koje su zapala posljednja vremena."},{"v":12,"t":"Tko dakle misli da stoji, neka pazi da ne padne."},{"v":13,"t":"Nije vas zahvatila druga kušnja osim ljudske. Ta vjeran je Bog: neće pustiti da budete kušani preko svojih sila, nego će s kušnjom dati i ishod da možete izdržati."},{"v":14,"t":"Zato, ljubljeni moji, bježite od idolopoklonstva."},{"v":15,"t":"Kao razumnima velim: sudite sami što govorim."},{"v":16,"t":"Čaša blagoslovna koju blagoslivljamo nije li zajedništvo krvi Kristove? Kruh koji lomimo nije li zajedništvo tijela Kristova?"},{"v":17,"t":"Budući da je jedan kruh, jedno smo tijelo mi mnogi; ta svi smo dionici jednoga kruha."},{"v":18,"t":"Gledajte Izraela po tijelu! Koji blaguju žrtve nisu li zajedničari žrtvenika?"},{"v":19,"t":"Što dakle hoću reći? Idolska žrtva da je nešto? Ili idol da je nešto?"},{"v":20,"t":"Naprotiv, da pogani vrazima žrtvuju, ne Bogu. A neću da budete zajedničari vražji."},{"v":21,"t":"Ne možete piti čašu Gospodnju i čašu vražju. Ne možete biti sudionici stola Gospodnjega i stola vražjega."},{"v":22,"t":"Ili da izazivamo ljubomor Gospodnji? Zar smo jači od njega?"},{"v":23,"t":"“Sve je slobodno!” Ali - sve ne koristi. “Sve je dopušteno!” Ali - sve ne saziđuje."},{"v":24,"t":"Nitko neka ne traži svoje, nego dobro drugoga."},{"v":25,"t":"Sve što se prodaje na tržnici, jedite ništa ne ispitujući poradi savjesti."},{"v":26,"t":"Ta Gospodnja je zemlja i sve na njoj!"},{"v":27,"t":"Pozove li vas koji nevjernik i želite se odazvati, jedite što vam se ponudi ništa ne ispitujući poradi savjesti."},{"v":28,"t":"Ako vam tko reče: “To je žrtvovano”, ne jedite poradi onoga koji vas je upozorio, i savjesti."},{"v":29,"t":"Savjesti mislim, ne svoje, nego onoga drugoga. Ta zašto da moju slobodu druga savjest sudi?"},{"v":30,"t":"Ako sa zahvalom sudjelujem, zašto da me grde zbog onoga za što zahvaljujem?"},{"v":31,"t":"Dakle, ili jeli, ili pili, ili drugo što činili, sve na slavu Božju činite."},{"v":32,"t":"Ne budite na sablazan ni Židovima, ni Grcima, ni Crkvi Božjoj,"},{"v":33,"t":"kao što i ja svima u svemu ugađam ne tražeći svoju korist, nego što koristi mnogima na spasenje."}]},"11":{"fa":[{"v":1,"t":"پس اقتدا به من نمایید چنانکه من نیز به مسیح می‌کنم."},{"v":2,"t":"اما‌ای برادران شما را تحسین می‌نمایم ازاین جهت که در هرچیز مرا یاد می‌دارید و اخبار رابطوری که به شما سپردم، حفظ می‌نمایید."},{"v":3,"t":"اما می‌خواهم شما بدانید که سر هر مرد، مسیح است و سر زن، مرد و سر مسیح، خدا."},{"v":4,"t":"هرمردی که سرپوشیده دعا یا نبوت کند، سر خود رارسوا می‌نماید."},{"v":5,"t":"اما هر زنی که سر برهنه دعا یانبوت کند، سر خود را رسوا می‌سازد، زیرا این چنان است که تراشیده شود."},{"v":6,"t":"زیرا اگر زن نمی پوشد، موی را نیز ببرد؛ و اگر زن را موی بریدن یا تراشیدن قبیح است، باید بپوشد."},{"v":7,"t":"زیراکه مرد را نباید سر خود بپوشد چونکه او صورت و جلال خداست، اما زن جلال مرد است."},{"v":8,"t":"زیراکه مرد از زن نیست بلکه زن از مرد است."},{"v":9,"t":"و نیزمرد بجهت زن آفریده نشد، بلکه زن برای مرد."},{"v":10,"t":"از این جهت زن می‌باید عزتی بر سر داشته باشد به‌سبب فرشتگان."},{"v":11,"t":"لیکن زن از مرد جدانیست و مرد هم جدا از زن نیست در خداوند."},{"v":12,"t":"زیرا چنانکه زن از مرد است، همچنین مرد نیزبوسیله زن، لیکن همه‌چیز از خدا."},{"v":13,"t":"در دل خود انصاف دهید: آیا شایسته است که زن ناپوشیده نزد خدا دعا کند؟"},{"v":14,"t":"آیا خودطبیعت شما را نمی آموزد که اگر مرد موی درازدارد، او را عار می‌باشد؟"},{"v":15,"t":"و اگر زن موی درازدارد، او را فخر است، زیرا که موی بجهت پرده بدو داده شد؟"},{"v":16,"t":"و اگر کسی ستیزه گر باشد، ما وکلیساهای خدا را چنین عادتی نیست."},{"v":17,"t":"لیکن چون این حکم را به شما می‌کنم، شمارا تحسین نمی کنم، زیرا که شما نه از برای بهتری بلکه برای بدتری جمع می‌شوید."},{"v":18,"t":"زیرا اولاهنگامی که شما در کلیسا جمع می‌شوید، می‌شنوم که در میان شما شقاقها روی می‌دهد وقدری از آن را باور می‌کنم."},{"v":19,"t":"از آن جهت که لازم است در میان شما بدعتها نیز باشد تا که مقبولان از شما ظاهر گردند."},{"v":20,"t":"پس چون شما دریک جا جمع می‌شوید، ممکن نیست که شام خداوند خورده شود،"},{"v":21,"t":"زیرا در وقت خوردن هرکس شام خود را پیشتر می‌گیرد و یکی گرسنه و دیگری مست می‌شود."},{"v":22,"t":"مگر خانه‌ها برای خوردن و آشامیدن ندارید؟ یا کلیسای خدا راتحقیر می‌نمایید و آنانی را که ندارند شرمنده می‌سازید؟ به شما چه بگویم؟ آیا در این امر شمارا تحسین نمایم؟ تحسین نمی نمایم!"},{"v":23,"t":"زیرا من از خداوند یافتم، آنچه به شما نیزسپردم که عیسی خداوند در شبی که او را تسلیم کردند، نان را گرفت"},{"v":24,"t":"و شکر نموده، پاره کرد وگفت: «بگیرید بخورید. این است بدن من که برای شما پاره می‌شود. این را به یادگاری من به‌جاآرید.»"},{"v":25,"t":"و همچنین پیاله را نیز بعد از شام وگفت: «این پیاله عهد جدید است در خون من. هرگاه این را بنوشید، به یادگاری من بکنید.»"},{"v":26,"t":"زیرا هرگاه این نان را بخورید و این پیاله رابنوشید، موت خداوند را ظاهر می‌نمایید تاهنگامی که بازآید."},{"v":27,"t":"پس هرکه بطور ناشایسته نان را بخورد وپیاله خداوند را بنوشد، مجرم بدن و خون خداوند خواهد بود."},{"v":28,"t":"اما هر شخص خود راامتحان کند و بدینطرز از آن نان بخورد و از آن پیاله بنوشد."},{"v":29,"t":"زیرا هرکه می‌خورد و می‌نوشد، فتوای خود را می‌خورد و می‌نوشد اگر بدن خداوند را تمییز نمی کند."},{"v":30,"t":"از این سبب بسیاری از شما ضعیف و مریض‌اند و بسیاری خوابیده‌اند."},{"v":31,"t":"اما اگر برخود حکم می‌کردیم، حکم بر مانمی شد."},{"v":32,"t":"لکن هنگامی که بر ما حکم می‌شود، از خداوند تادیب می‌شویم مبادا با اهل دنیا بر ماحکم شود."},{"v":33,"t":"لهذا‌ای برادران من، چون بجهت خوردن جمع می‌شوید، منتظر یکدیگر باشید."},{"v":34,"t":"و اگرکسی گرسنه باشد، در خانه بخورد، مبادا بجهت عقوبت جمع شوید. و چون بیایم، مابقی را منتظم خواهم نمود."}],"en":[{"v":1,"t":"Be imitators of me, even as I also am of Christ."},{"v":2,"t":"Now I praise you, brothers, that you remember me in all things, and hold firm the traditions, even as I delivered them to you."},{"v":3,"t":"But I would have you know that the head of every man is Christ, and the head of the woman is man, and the head of Christ is God."},{"v":4,"t":"Every man praying or prophesying, having his head covered, dishonors his head."},{"v":5,"t":"But every woman praying or prophesying with her head uncovered dishonors her head. For it is one and the same thing as if she were shaved."},{"v":6,"t":"For if a woman is not covered, let her hair also be cut off. But if it is shameful for a woman to have her hair cut off or be shaved, let her be covered."},{"v":7,"t":"For a man indeed ought not to have his head covered, because he is the image and glory of God, but the woman is the glory of the man."},{"v":8,"t":"For man is not from woman, but woman from man;"},{"v":9,"t":"for man wasn’t created for the woman, but woman for the man."},{"v":10,"t":"For this cause the woman ought to have authority over her own head, because of the angels."},{"v":11,"t":"Nevertheless, neither is the woman independent of the man, nor the man independent of the woman, in the Lord."},{"v":12,"t":"For as woman came from man, so a man also comes through a woman; but all things are from God."},{"v":13,"t":"Judge for yourselves. Is it appropriate that a woman pray to God unveiled?"},{"v":14,"t":"Doesn’t even nature itself teach you that if a man has long hair, it is a dishonor to him?"},{"v":15,"t":"But if a woman has long hair, it is a glory to her, for her hair is given to her for a covering."},{"v":16,"t":"But if any man seems to be contentious, we have no such custom, neither do God’s assemblies."},{"v":17,"t":"But in giving you this command I don’t praise you, because you come together not for the better but for the worse."},{"v":18,"t":"For first of all, when you come together in the assembly, I hear that divisions exist among you, and I partly believe it."},{"v":19,"t":"For there also must be factions among you, that those who are approved may be revealed among you."},{"v":20,"t":"When therefore you assemble yourselves together, it is not the Lord’s supper that you eat."},{"v":21,"t":"For in your eating each one takes his own supper first. One is hungry, and another is drunken."},{"v":22,"t":"What, don’t you have houses to eat and to drink in? Or do you despise God’s assembly and put them to shame who don’t have enough? What shall I tell you? Shall I praise you? In this I don’t praise you."},{"v":23,"t":"For I received from the Lord that which also I delivered to you, that the Lord Jesus on the night in which he was betrayed took bread."},{"v":24,"t":"When he had given thanks, he broke it and said, “Take, eat. This is my body, which is broken for you. Do this in memory of me.”"},{"v":25,"t":"In the same way he also took the cup after supper, saying, “This cup is the new covenant in my blood. Do this, as often as you drink, in memory of me.”"},{"v":26,"t":"For as often as you eat this bread and drink this cup, you proclaim the Lord’s death until he comes."},{"v":27,"t":"Therefore whoever eats this bread or drinks the Lord’s cup in a way unworthy of the Lord will be guilty of the body and the blood of the Lord."},{"v":28,"t":"But let a man examine himself, and so let him eat of the bread and drink of the cup."},{"v":29,"t":"For he who eats and drinks in an unworthy way eats and drinks judgment to himself if he doesn’t discern the Lord’s body."},{"v":30,"t":"For this cause many among you are weak and sickly, and not a few sleep."},{"v":31,"t":"For if we discerned ourselves, we wouldn’t be judged."},{"v":32,"t":"But when we are judged, we are disciplined by the Lord, that we may not be condemned with the world."},{"v":33,"t":"Therefore, my brothers, when you come together to eat, wait for one another."},{"v":34,"t":"But if anyone is hungry, let him eat at home, lest your coming together be for judgment. The rest I will set in order whenever I come."}],"hr":[{"v":1,"t":"Nasljedovatelji moji budite, kao što sam i ja Kristov."},{"v":2,"t":"Hvalim vas što me se u svemu sjećate i držite se predaja kako vam predadoh."},{"v":3,"t":"Ali htio bih da znate: svakomu je mužu glava Krist, glava ženi muž, a glava Kristu Bog."},{"v":4,"t":"Svaki muž koji se moli ili prorokuje pokrivene glave sramoti glavu svoju."},{"v":5,"t":"Svaka pak žena koja se moli ili prorokuje gologlava sramoti glavu svoju. Ta to je isto kao da je obrijana."},{"v":6,"t":"Jer ako se žena ne pokriva, neka se šiša; ako li je pak ružno ženi šišati se ili brijati, neka se pokrije."},{"v":7,"t":"A muž ne mora pokrivati glave, ta slika je i slava Božja; a žena je slava muževa."},{"v":8,"t":"Jer nije muž od žene, nego žena od muža."},{"v":9,"t":"I nije stvoren muž radi žene, nego žena radi muža."},{"v":10,"t":"Zato žena treba da ima “vlast” na glavi poradi anđela."},{"v":11,"t":"Ipak, u Gospodinu - ni žena bez muža, ni muž bez žene!"},{"v":12,"t":"Jer kao što je žena od muža, tako je i muž po ženi; a sve je od Boga."},{"v":13,"t":"Sami sudite dolikuje li da se žena gologlava Bogu moli?"},{"v":14,"t":"Ne uči li nas i sama narav da je mužu sramota ako goji kosu?"},{"v":15,"t":"A ženi je dika ako je goji jer kosa joj je dana mjesto prijevjesa."},{"v":16,"t":"Ako je kome do prepirke, takva običaja mi nemamo, a ni Crkve Božje."},{"v":17,"t":"Kad već dajem ta upozorenja, ne mogu pohvaliti što se ne sastajete na bolje, nego na gore."},{"v":18,"t":"Ponajprije čujem, djelomično i vjerujem: kad se okupite na Sastanak, da su među vama razdori."},{"v":19,"t":"Treba doista da i podjela bude među vama da se očituju prokušani među vama."},{"v":20,"t":"Kad se dakle tako zajedno sastajete, to nije blagovanje Gospodnje večere:"},{"v":21,"t":"ta svatko se pri blagovanju prihvati svoje večere te jedan gladuje, a drugi se opija."},{"v":22,"t":"Zar nemate kuća da jedete i pijete? Ili Crkvu Božju prezirete i postiđujete one koji nemaju? Što da vam kažem? Da vas pohvalim? U tom vas ne hvalim."},{"v":23,"t":"Doista, ja od Gospodina primih što vama predadoh: Gospodin Isus one noći kad bijaše predan uze kruh,"},{"v":24,"t":"zahvalivši razlomi i reče: “Ovo je tijelo moje - za vas. Ovo činite meni na spomen.”"},{"v":25,"t":"Tako i čašu po večeri govoreći: “Ova čaša novi je Savez u mojoj krvi. Ovo činite kad god pijete, meni na spomen.”"},{"v":26,"t":"Doista, kad god jedete ovaj kruh i pijete čašu, smrt Gospodnju navješćujete dok on ne dođe."},{"v":27,"t":"Stoga, tko god jede kruh ili pije čašu Gospodnju nedostojno, bit će krivac tijela i krvi Gospodnje."},{"v":28,"t":"Neka se dakle svatko ispita pa tada od kruha jede i iz čaše pije."},{"v":29,"t":"Jer tko jede i pije, sud sebi jede i pije ako ne razlikuje Tijela."},{"v":30,"t":"Zato su među vama mnogi nejaki i nemoćni, i spavaju mnogi."},{"v":31,"t":"Jer kad bismo sami sebe sudili, ne bismo bili suđeni."},{"v":32,"t":"A kad nas sudi Gospodin, odgaja nas da ne budemo sa svijetom osuđeni."},{"v":33,"t":"Zato, braćo moja, kad se sastajete na blagovanje, pričekajte jedni druge."},{"v":34,"t":"Je li tko gladan, kod kuće neka jede da se ne sastajete na osudu. Drugo ću urediti kada dođem."}]},"12":{"fa":[{"v":1,"t":"اما درباره عطایای روحانی، ای برادران نمی خواهم شما بی‌خبر باشید."},{"v":2,"t":"می دانید هنگامی که امت‌ها می‌بودید، به سوی بتهای گنگ برده می‌شدید بطوری که شما رامی بردند."},{"v":3,"t":"پس شما را خبر می‌دهم که هرکه متکلم به روح خدا باشد، عیسی را اناتیمانمی گوید و احدی جزیه روح‌القدس عیسی راخداوند نمی تواند گفت."},{"v":4,"t":"و نعمتها انواع است ولی روح همان."},{"v":5,"t":"وخدمتها انواع است اما خداوند همان."},{"v":6,"t":"و عملهاانواع است لکن همان خدا همه را در همه عمل می‌کند."},{"v":7,"t":"ولی هرکس را ظهور روح بجهت منفعت عطا می‌شود."},{"v":8,"t":"زیرا یکی را بوساطت روح، کلام حکمت داده می‌شود و دیگری را کلام علم، بحسب همان روح."},{"v":9,"t":"و یکی را ایمان به همان روح و دیگری را نعمتهای شفا دادن به همان روح."},{"v":10,"t":"و یکی را قوت معجزات ودیگری را نبوت و یکی را تمییز ارواح و دیگری را اقسام زبانها و دیگری را ترجمه زبانها."},{"v":11,"t":"لکن در جمیع اینها همان یک روح فاعل است که هرکس را فرد بحسب اراده خود تقسیم می‌کند."},{"v":12,"t":"زیرا چنانکه بدن یک است و اعضای متعدددارد و تمامی اعضای بدن اگرچه بسیار است یکتن می‌باشد، همچنین مسیح نیز می‌باشد."},{"v":13,"t":"زیرا که جمیع ما به یک روح در یک بدن تعمیدیافتم، خواه یهود، خواه یونانی، خواه غلام، خواه آزاد و همه از یک روح نوشانیده شدیم."},{"v":14,"t":"زیرابدن یک عضو نیست بلکه بسیار است."},{"v":15,"t":"اگر پاگوید چونکه دست نیستم از بدن نمی باشم، آیابدین سبب از بدن نیست؟"},{"v":16,"t":"و اگر گوش گویدچونکه چشم نیم از بدن نیستم، آیا بدین سبب ازبدن نیست؟"},{"v":17,"t":"اگر تمام بدن چشم بودی، کجامی بود شنیدن و اگر همه شنیدن بودی کجا می‌بودبوییدن؟"},{"v":18,"t":"لکن الحال خدا هریک از اعضا را دربدن نهاد برحسب اراده خود."},{"v":19,"t":"و اگر همه یک عضو بودی بدن کجا می‌بود؟"},{"v":20,"t":"اما الان اعضابسیار است لیکن بدن یک."},{"v":21,"t":"و چشم دست رانمی تواند گفت که محتاج تو نیستم یا سر پایها رانیز که احتیاج به شما ندارم."},{"v":22,"t":"بلکه علاوه بر این، آن اعضای بدن که ضعیفتر می‌نمایند، لازم ترمی باشند."},{"v":23,"t":"و آنها را که پست‌تر اجزای بدن می‌پندارم، عزیزتر می‌داریم و اجزای قبیح ماجمال افضل دارد."},{"v":24,"t":"لکن اعضای جمیله ما رااحتیاجی نیست، بلکه خدا بدن را مرتب ساخت بقسمی که ناقص را بیشتر حرمت داد،"},{"v":25,"t":"تا که جدایی در بدن نیفتد، بلکه اعضا به برابری در فکریکدیگر باشند."},{"v":26,"t":"و اگر یک عضو دردمند گردد، سایر اعضا با آن همدرد باشند و اگر عضوی عزت یابد، باقی اعضا با او به خوشی آیند."},{"v":27,"t":"اما شما بدن مسیح هستید و فرد اعضای آن می‌باشید."},{"v":28,"t":"و خدا قرارداد بعضی را درکلیسا: اول رسولان، دوم انبیا، سوم معلمان، بعدقوات، پس نعمتهای شفا دادن و اعانات و تدابیر واقسام زبانها."},{"v":29,"t":"آیا همه رسول هستند، یا همه انبیا، یا همه معلمان، یا همه قوات؟"},{"v":30,"t":"یا همه نعمتهای شفا دارند، یا همه به زبانها متکلم هستند، یا همه ترجمه می‌کنند؟"},{"v":31,"t":"لکن نعمتهای بهتر را به غیرت بطلبید و طریق افضلتر نیز به شمانشان می‌دهم."}],"en":[{"v":1,"t":"Now concerning spiritual things, brothers, I don’t want you to be ignorant."},{"v":2,"t":"You know that when you were heathen, you were led away to those mute idols, however you might be led."},{"v":3,"t":"Therefore I make known to you that no man speaking by God’s Spirit says, “Jesus is accursed.” No one can say, “Jesus is Lord,” but by the Holy Spirit."},{"v":4,"t":"Now there are various kinds of gifts, but the same Spirit."},{"v":5,"t":"There are various kinds of service, and the same Lord."},{"v":6,"t":"There are various kinds of workings, but the same God who works all things in all."},{"v":7,"t":"But to each one is given the manifestation of the Spirit for the profit of all."},{"v":8,"t":"For to one is given through the Spirit the word of wisdom, and to another the word of knowledge according to the same Spirit,"},{"v":9,"t":"to another faith by the same Spirit, and to another gifts of healings by the same Spirit,"},{"v":10,"t":"and to another workings of miracles, and to another prophecy, and to another discerning of spirits, to another different kinds of languages, and to another the interpretation of languages."},{"v":11,"t":"But the one and the same Spirit produces all of these, distributing to each one separately as he desires."},{"v":12,"t":"For as the body is one and has many members, and all the members of the body, being many, are one body; so also is Christ."},{"v":13,"t":"For in one Spirit we were all baptized into one body, whether Jews or Greeks, whether bond or free; and were all given to drink into one Spirit."},{"v":14,"t":"For the body is not one member, but many."},{"v":15,"t":"If the foot would say, “Because I’m not the hand, I’m not part of the body,” it is not therefore not part of the body."},{"v":16,"t":"If the ear would say, “Because I’m not the eye, I’m not part of the body,” it’s not therefore not part of the body."},{"v":17,"t":"If the whole body were an eye, where would the hearing be? If the whole were hearing, where would the smelling be?"},{"v":18,"t":"But now God has set the members, each one of them, in the body, just as he desired."},{"v":19,"t":"If they were all one member, where would the body be?"},{"v":20,"t":"But now they are many members, but one body."},{"v":21,"t":"The eye can’t tell the hand, “I have no need for you,” or again the head to the feet, “I have no need for you.”"},{"v":22,"t":"No, much rather, those members of the body which seem to be weaker are necessary."},{"v":23,"t":"Those parts of the body which we think to be less honorable, on those we bestow more abundant honor; and our unpresentable parts have more abundant modesty,"},{"v":24,"t":"while our presentable parts have no such need. But God composed the body together, giving more abundant honor to the inferior part,"},{"v":25,"t":"that there should be no division in the body, but that the members should have the same care for one another."},{"v":26,"t":"When one member suffers, all the members suffer with it. When one member is honored, all the members rejoice with it."},{"v":27,"t":"Now you are the body of Christ, and members individually."},{"v":28,"t":"God has set some in the assembly: first apostles, second prophets, third teachers, then miracle workers, then gifts of healings, helps, governments, and various kinds of languages."},{"v":29,"t":"Are all apostles? Are all prophets? Are all teachers? Are all miracle workers?"},{"v":30,"t":"Do all have gifts of healings? Do all speak with various languages? Do all interpret?"},{"v":31,"t":"But earnestly desire the best gifts. Moreover, I show a most excellent way to you."}],"hr":[{"v":1,"t":"O darima Duha ne bih, braćo, htio da budete u neznanju."},{"v":2,"t":"Znate kako ste se dok bijaste pogani, zavedeni, zanosili nijemim idolima."},{"v":3,"t":"Zato vam obznanjujem: nitko tko u Duhu Božjem govori ne kaže: “Prokletstvo Isusu”. I nitko ne može reći: “Gospodin Isus” osim u Duhu Svetom."},{"v":4,"t":"Različiti su dari, a isti Duh;"},{"v":5,"t":"i različite službe, a isti Gospodin;"},{"v":6,"t":"i različita djelovanja, a isti Bog koji čini sve u svima."},{"v":7,"t":"A svakomu se daje očitovanje Duha na korist."},{"v":8,"t":"Doista, jednomu se po Duhu daje riječ mudrosti, drugomu riječ spoznanja po tom istom Duhu;"},{"v":9,"t":"drugomu vjera u tom istom Duhu, drugomu dari liječenja u tom jednom Duhu;"},{"v":10,"t":"drugomu čudotvorstva, drugomu prorokovanje, drugomu razlučivanje duhova, drugomu različiti jezici, drugomu tumačenje jezika."},{"v":11,"t":"A sve to djeluje jedan te isti Duh dijeleći svakomu napose kako hoće."},{"v":12,"t":"Doista, kao što je tijelo jedno te ima mnogo udova, a svi udovi tijela iako mnogi, jedno su tijelo - tako i Krist."},{"v":13,"t":"Ta u jednom Duhu svi smo u jedno tijelo kršteni, bilo Židovi, bilo Grci, bilo robovi, bilo slobodni. I svi smo jednim Duhom napojeni."},{"v":14,"t":"Ta ni tijelo nije jedan ud, nego mnogi."},{"v":15,"t":"Rekne li noga: “Nisam ruka, nisam od tijela”, zar zbog toga nije od tijela?"},{"v":16,"t":"I rekne li uho: “Nisam oko, nisam od tijela”, zar zbog toga nije od tijela?"},{"v":17,"t":"Kad bi sve tijelo bilo oko, gdje bi bio sluh? Kad bi sve bilo sluh, gdje bi bio njuh?"},{"v":18,"t":"A ovako, Bog je rasporedio udove, svaki od njih u tijelu, kako je htio."},{"v":19,"t":"Kad bi svi bili jedan ud, gdje bio bilo tijelo?"},{"v":20,"t":"A ovako, mnogi udovi - jedno tijelo!"},{"v":21,"t":"Ne može oko reći ruci: “Ne trebam te”, ili pak glava nogama: “Ne trebam vas.”"},{"v":22,"t":"Naprotiv, mnogo su potrebniji udovi tijela koji izgledaju slabiji."},{"v":23,"t":"A udove koje smatramo nečasnijima, okružujemo većom čašću. I s nepristojnima se pristojnije postupa,"},{"v":24,"t":"a pristojni toga ne trebaju. Nego, Bog je tako sastavio tijelo da je posljednjem udu dao izobilniju čast"},{"v":25,"t":"da ne bude razdora u tijelu, nego da se udovi jednako brinu jedni za druge."},{"v":26,"t":"I ako trpi jedan ud, trpe zajedno svi udovi; ako li se slavi jedan ud, raduju se zajedno svi udovi."},{"v":27,"t":"A vi ste tijelo Kristovo i, pojedinačno, udovi."},{"v":28,"t":"I neke postavi Bog u Crkvi: prvo za apostole, drugo za proroke, treće za učitelje; onda čudesa, onda dari liječenja; zbrinjavanja, upravljanja, razni jezici."},{"v":29,"t":"Zar su svi apostoli? Zar svi proroci? Zar svi učitelji? Zar svi čudotvorci?"},{"v":30,"t":"Zar svi imaju dare liječenja? Zar svi govore jezike? Zar svi tumače?"},{"v":31,"t":"Čeznite za višim darima! A evo vam puta najizvrsnijega!"}]},"13":{"fa":[{"v":1,"t":"اگر به زبانهای مردم و فرشتگان سخن گویم و محبت نداشته باشم، مثل نحاس صدادهنده و سنج فغان کننده شده‌ام."},{"v":2,"t":"و اگرنبوت داشته باشم و جمیع اسرار و همه علم رابدانم و ایمان کامل داشته باشم بحدی که کوهها رانقل کنم و محبت نداشته باشم، هیچ هستم."},{"v":3,"t":"واگر جمیع اموال خود را صدقه دهم و بدن خود رابسپارم تا سوخته شود و محبت نداشته باشم، هیچ سود نمی برم."},{"v":4,"t":"محبت حلیم و مهربان است؛ محبت حسد نمی برد؛ محبت کبر و غرور ندارد؛"},{"v":5,"t":"اطوار ناپسندیده ندارد و نفع خود را طالب نمی شود؛ خشم نمی گیرد و سوءظن ندارد؛"},{"v":6,"t":"ازناراستی خوشوقت نمی گردد، ولی با راستی شادی می‌کند؛"},{"v":7,"t":"در همه‌چیز صبر می‌کند و همه را باور می‌نماید؛ در همه حال امیدوار می‌باشد وهر چیز را متحمل می‌باشد."},{"v":8,"t":"محبت هرگز ساقط نمی شود و اما اگر نبوتهاباشد، نیست خواهد شد و اگر زبانها، انتها خواهد پذیرفت و اگر علم، زایل خواهد گردید."},{"v":9,"t":"زیراجزئی علمی داریم و جزئی نبوت می‌نماییم،"},{"v":10,"t":"لکن هنگامی که کامل آید، جزئی نیست خواهد گردید."},{"v":11,"t":"زمانی که طفل بودم، چون طفل حرف می‌زدم و چون طفل فکر می‌کردم و مانندطفل تعقل می‌نمودم. اما چون مرد شدم، کارهای طفلانه را ترک کردم."},{"v":12,"t":"زیرا که الحال در آینه بطور معما می‌بینم، لکن آن وقت روبرو؛ الان جزئی معرفتی دارم، لکن آن وقت خواهم شناخت، چنانکه نیز شناخته شدم."},{"v":13,"t":"و الحال این سه چیز باقی است: یعنی‌ایمان و امید ومحبت. اما بزرگتر از اینها محبت است."}],"en":[{"v":1,"t":"If I speak with the languages of men and of angels, but don’t have love, I have become sounding brass or a clanging cymbal."},{"v":2,"t":"If I have the gift of prophecy, and know all mysteries and all knowledge, and if I have all faith, so as to remove mountains, but don’t have love, I am nothing."},{"v":3,"t":"If I give away all my goods to feed the poor, and if I give my body to be burned, but don’t have love, it profits me nothing."},{"v":4,"t":"Love is patient and is kind. Love doesn’t envy. Love doesn’t brag, is not proud,"},{"v":5,"t":"doesn’t behave itself inappropriately, doesn’t seek its own way, is not provoked, takes no account of evil;"},{"v":6,"t":"doesn’t rejoice in unrighteousness, but rejoices with the truth;"},{"v":7,"t":"bears all things, believes all things, hopes all things, and endures all things."},{"v":8,"t":"Love never fails. But where there are prophecies, they will be done away with. Where there are various languages, they will cease. Where there is knowledge, it will be done away with."},{"v":9,"t":"For we know in part and we prophesy in part;"},{"v":10,"t":"but when that which is complete has come, then that which is partial will be done away with."},{"v":11,"t":"When I was a child, I spoke as a child, I felt as a child, I thought as a child. Now that I have become a man, I have put away childish things."},{"v":12,"t":"For now we see in a mirror, dimly, but then face to face. Now I know in part, but then I will know fully, even as I was also fully known."},{"v":13,"t":"But now faith, hope, and love remain—these three. The greatest of these is love."}],"hr":[{"v":1,"t":"Kad bih sve jezike ljudske govorio i anđeoske, a ljubavi ne bih imao, bio bih mjed što ječi ili cimbal što zveči."},{"v":2,"t":"Kad bih imao dar prorokovanja i znao sva otajstva i sve spoznanje; i kad bih imao svu vjeru da bih i gore premještao, a ljubavi ne bih imao - ništa sam!"},{"v":3,"t":"I kad bih razdao sav svoj imutak i kad bih predao tijelo svoje da se sažeže, a ljubavi ne bih imao - ništa mi ne bi koristilo."},{"v":4,"t":"Ljubav je velikodušna, dobrostiva je ljubav, ne zavidi, ljubav se ne hvasta, ne nadima se;"},{"v":5,"t":"nije nepristojna, ne traži svoje, nije razdražljiva, ne pamti zlo;"},{"v":6,"t":"ne raduje se nepravdi, a raduje se istini;"},{"v":7,"t":"sve pokriva, sve vjeruje, svemu se nada, sve podnosi."},{"v":8,"t":"Ljubav nikad ne prestaje. Prorokovanja? Uminut će. Jezici? Umuknut će. Spoznanje? Uminut će."},{"v":9,"t":"Jer djelomično je naše spoznanje, i djelomično prorokovanje."},{"v":10,"t":"A kada dođe ono savršeno, uminut će ovo djelomično."},{"v":11,"t":"Kad bijah nejače, govorah kao nejače, mišljah kao nejače, rasuđivah kao nejače. A kad postadoh zreo čovjek, odbacih ono nejačko."},{"v":12,"t":"Doista, sada gledamo kroza zrcalo, u zagonetki, a tada - licem u lice! Sada spoznajem djelomično, a tada ću spoznati savršeno, kao što sam i spoznat!"},{"v":13,"t":"A sada: ostaju vjera, ufanje i ljubav - to troje - ali najveća je među njima ljubav."}]},"14":{"fa":[{"v":1,"t":"در‌پی محبت بکوشید و عطایای روحانی را به غیرت بطلبید، خصوص اینکه نبوت کنید."},{"v":2,"t":"زیرا کسی‌که به زبانی سخن می‌گوید، نه به مردم بلکه به خدا می‌گوید، زیراهیچ‌کس نمی فهمد لیکن در روح به اسرار تکلم می‌نماید."},{"v":3,"t":"اما آنکه نبوت می‌کند، مردم را برای بنا و نصیحت و تسلی می‌گوید."},{"v":4,"t":"هرکه به زبانی می‌گوید، خود را بنا می‌کند، اما آنکه نبوت می‌نماید، کلیسا را بنا می‌کند."},{"v":5,"t":"و خواهش دارم که همه شما به زبانها تکلم کنید، لکن بیشتر اینکه نبوت نمایید زیرا کسی‌که نبوت کند بهتر است ازکسی‌که به زبانها حرف زند، مگر آنکه ترجمه کندتا کلیسا بنا شود."},{"v":6,"t":"اما الحال‌ای برادران اگر نزد شما آیم و به زبانها سخن رانم، شما را چه سود می‌بخشم؟ مگرآنکه شما را به مکاشفه یا به معرفت یا به نبوت یا به تعلیم گویم."},{"v":7,"t":"و همچنین چیزهای بیجان که صدا می‌دهد چون نی یا بربط اگر در صداها فرق نکند، چگونه آواز نی یا بربط فهمیده می‌شود؟"},{"v":8,"t":"زیر اگر کرنا نیز صدای نامعلوم دهد که خود رامهیای جنگ می‌سازد؟"},{"v":9,"t":"همچنین شما نیز به زبان، سخن مفهوم نگویید، چگونه معلوم می‌شودآن چیزی که گفته شد زیرا که به هوا سخن خواهید گفت؟"},{"v":10,"t":"زیرا که انواع زبانهای دنیاهرقدر زیاده باشد، ولی یکی بی‌معنی نیست."},{"v":11,"t":"پس هرگاه قوت زبان را نمی دانم، نزد متکلم بربری می‌باشم و آنکه سخن گوید نزد من بربری می‌باشد."},{"v":12,"t":"همچنن شما نیز چونکه غیورعطایای روحانی هستید بطلبید اینکه برای بنای کلیسا افزوده شوید."},{"v":13,"t":"بنابراین کسی‌که به زبانی سخن می‌گوید، دعا بکند تا ترجمه نماید."},{"v":14,"t":"زیرا اگر به زبانی دعاکنم، روح من دعا می‌کند لکن عقل من برخوردارنمی شود."},{"v":15,"t":"پس مقصود چیست؟ به روح دعاخواهم کرد و به عقل نیز دعا خواهم نمود؛ به روح سرود خواهم خواند و به عقل نیز خواهم خواند."},{"v":16,"t":"زیرا اگر در روح تبرک می‌خوانی، چگونه آن کسی‌که به منزلت امی است، به شکر تو آمین گوید و حال آنکه نمی فهمد چه می‌گویی؟"},{"v":17,"t":"زیرا تو البته خوب شکر می‌کنی، لکن آن دیگربنا نمی شود."},{"v":18,"t":"خدا را شکر می‌کنم که زیادتر ازهمه شما به زبانها حرف می‌زنم."},{"v":19,"t":"لکن در کلیسابیشتر می‌پسندم که پنج کلمه به عقل خود گویم تادیگران را نیز تعلیم دهم از آنکه هزاران کلمه به زبان بگویم."},{"v":20,"t":"‌ای برادران، در فهم اطفال مباشید بلکه در بدخویی اطفال باشید و در فهم رشید."},{"v":21,"t":"درتورات مکتوب است که «خداوند می‌گوید به زبانهای بیگانه و لبهای غیر به این قوم سخن خواهم گفت و با این همه مرا نخواهند شنید.»"},{"v":22,"t":"پس زبانها نشانی است نه برای ایمان داران بلکه برای بی‌ایمانان؛ اما نبوت برای بی‌ایمان نیست بلکه برای ایمانداران است."},{"v":23,"t":"پس اگر تمام کلیسادر جایی جمع شوند و همه به زبانها حرف زنند وامیان یا بی‌ایمانان داخل شوند، آیا نمی گویند که دیوانه‌اید؟"},{"v":24,"t":"ولی اگر همه نبوت کنند و کسی ازبی ایمانان یا امیان درآید، از همه توبیخ می‌یابد واز همه ملزم می‌گردد،"},{"v":25,"t":"و خفایای قلب او ظاهرمی شود و همچنین به روی درافتاده، خدا راعبادت خواهد کرد و ندا خواهد داد که «فی الحقیقه خدا در میان شما است.»"},{"v":26,"t":"پس‌ای برادران مقصود این است که وقتی که جمع شوید، هریکی از شما سرودی دارد، تعلیمی دارد، زبانی دارد، مکاشفه‌ای دارد، ترجمه‌ای دارد، باید همه بجهت بنا بشود."},{"v":27,"t":"اگرکسی به زبانی سخن گوید، دو دو یا نهایت سه سه باشند، به ترتیب و کسی ترجمه کند."},{"v":28,"t":"اما اگرمترجمی نباشد، در کلیسا خاموش باشد و با خودو با خدا سخن گوید."},{"v":29,"t":"و از انبیا دو یا سه سخن بگویند و دیگران تمیز دهند."},{"v":30,"t":"و اگر چیزی به دیگری از اهل مجلس مکشوف شود، آن اول ساکت شود."},{"v":31,"t":"زیرا که همه می‌توانید یک یک نبوت کنید تا همه تعلیم یابند و همه نصیحت‌پذیرند."},{"v":32,"t":"و ارواح انبیا مطیع انبیا می‌باشند."},{"v":33,"t":"زیرا که او خدای تشویش نیست بلکه خدای سلامتی، چنانکه در همه کلیساهای مقدسان."},{"v":34,"t":"و زنان شما در کلیساها خاموش باشند زیرا که ایشان را حرف زدن جایز نیست بلکه اطاعت نمودن، چنانکه تورات نیز می‌گوید."},{"v":35,"t":"اما اگرمی خواهند چیزی بیاموزند، در خانه از شوهران خود بپرسند، چون زنان را در کلیسا حرف زدن قبیح است."},{"v":36,"t":"آیا کلام خدا از شما صادر شد یا به شما به تنهایی رسید؟"},{"v":37,"t":"اگر کسی خود را نبی یاروحانی پندارد، اقرار بکند که آنچه به شمامی نویسم، احکام خداوند است."},{"v":38,"t":"اما اگر کسی جاهل است، جاهل باشد."},{"v":39,"t":"پس‌ای برادران، نبوت را به غیرت بطلبید و از تکلم نمودن به زبانهامنع مکنید."},{"v":40,"t":"لکن همه‌چیز به شایستگی و انتظام باشد."}],"en":[{"v":1,"t":"Follow after love and earnestly desire spiritual gifts, but especially that you may prophesy."},{"v":2,"t":"For he who speaks in another language speaks not to men, but to God, for no one understands, but in the Spirit he speaks mysteries."},{"v":3,"t":"But he who prophesies speaks to men for their edification, exhortation, and consolation."},{"v":4,"t":"He who speaks in another language edifies himself, but he who prophesies edifies the assembly."},{"v":5,"t":"Now I desire to have you all speak with other languages, but even more that you would prophesy. For he is greater who prophesies than he who speaks with other languages, unless he interprets, that the assembly may be built up."},{"v":6,"t":"But now, brothers, if I come to you speaking with other languages, what would I profit you unless I speak to you either by way of revelation, or of knowledge, or of prophesying, or of teaching?"},{"v":7,"t":"Even lifeless things that make a sound, whether pipe or harp, if they didn’t give a distinction in the sounds, how would it be known what is piped or harped?"},{"v":8,"t":"For if the trumpet gave an uncertain sound, who would prepare himself for war?"},{"v":9,"t":"So also you, unless you uttered by the tongue words easy to understand, how would it be known what is spoken? For you would be speaking into the air."},{"v":10,"t":"There are, it may be, so many kinds of languages in the world, and none of them is without meaning."},{"v":11,"t":"If then I don’t know the meaning of the language, I would be to him who speaks a foreigner, and he who speaks would be a foreigner to me."},{"v":12,"t":"So also you, since you are zealous for spiritual gifts, seek that you may abound to the building up of the assembly."},{"v":13,"t":"Therefore let him who speaks in another language pray that he may interpret."},{"v":14,"t":"For if I pray in another language, my spirit prays, but my understanding is unfruitful."},{"v":15,"t":"What should I do? I will pray with the spirit, and I will pray with the understanding also. I will sing with the spirit, and I will sing with the understanding also."},{"v":16,"t":"Otherwise, if you bless with the spirit, how will he who fills the place of the unlearned say the “Amen” at your giving of thanks, seeing he doesn’t know what you say?"},{"v":17,"t":"For you most certainly give thanks well, but the other person is not built up."},{"v":18,"t":"I thank my God, I speak with other languages more than you all."},{"v":19,"t":"However, in the assembly I would rather speak five words with my understanding, that I might instruct others also, than ten thousand words in another language."},{"v":20,"t":"Brothers, don’t be children in thoughts, yet in malice be babies, but in thoughts be mature."},{"v":21,"t":"In the law it is written, “By men of strange languages and by the lips of strangers I will speak to this people. They won’t even listen to me that way, says the Lord.”"},{"v":22,"t":"Therefore other languages are for a sign, not to those who believe, but to the unbelieving; but prophesying is for a sign, not to the unbelieving, but to those who believe."},{"v":23,"t":"If therefore the whole assembly is assembled together and all speak with other languages, and unlearned or unbelieving people come in, won’t they say that you are crazy?"},{"v":24,"t":"But if all prophesy, and someone unbelieving or unlearned comes in, he is reproved by all, and he is judged by all."},{"v":25,"t":"And thus the secrets of his heart are revealed. So he will fall down on his face and worship God, declaring that God is among you indeed."},{"v":26,"t":"What is it then, brothers? When you come together, each one of you has a psalm, has a teaching, has a revelation, has another language, or has an interpretation. Let all things be done to build each other up."},{"v":27,"t":"If any man speaks in another language, let there be two, or at the most three, and in turn; and let one interpret."},{"v":28,"t":"But if there is no interpreter, let him keep silent in the assembly, and let him speak to himself and to God."},{"v":29,"t":"Let two or three of the prophets speak, and let the others discern."},{"v":30,"t":"But if a revelation is made to another sitting by, let the first keep silent."},{"v":31,"t":"For you all can prophesy one by one, that all may learn and all may be exhorted."},{"v":32,"t":"The spirits of the prophets are subject to the prophets,"},{"v":33,"t":"for God is not a God of confusion but of peace, as in all the assemblies of the saints."},{"v":34,"t":"Let the wives be quiet in the assemblies, for it has not been permitted for them to be talking except in submission, as the law also says,"},{"v":35,"t":"if they desire to learn anything. “Let them ask their own husbands at home, for it is shameful for a wife to be talking in the assembly.”"},{"v":36,"t":"What!? Was it from you that the word of God went out? Or did it come to you alone?"},{"v":37,"t":"If any man thinks himself to be a prophet or spiritual, let him recognize the things which I write to you, that they are the commandment of the Lord."},{"v":38,"t":"But if anyone is ignorant, let him be ignorant."},{"v":39,"t":"Therefore, brothers, desire earnestly to prophesy, and don’t forbid speaking with other languages."},{"v":40,"t":"Let all things be done decently and in order."}],"hr":[{"v":1,"t":"Težite za ljubavlju, čeznite za darima Duha, a najvećma da prorokujete."},{"v":2,"t":"Jer tko govori drugim jezikom, ne govori ljudima nego Bogu: nitko ga ne razumije jer Duhom govori stvari tajanstvene."},{"v":3,"t":"Tko pak prorokuje, ljudima govori: izgrađuje, hrabri, tješi."},{"v":4,"t":"Tko govori drugim jezikom, sam sebe izgrađuje, a tko prorokuje, Crkvu izgrađuje."},{"v":5,"t":"A htio bih da vi svi govorite drugim jezicima, ali većma da prorokujete. Jer veći je tko prorokuje, negoli tko govori drugim jezicima, osim ako protumači Crkvi radi izgrađivanja."},{"v":6,"t":"A sada, braćo, kad bih došao k vama govoreći drugim jezicima, što bi vam koristilo kad vam ne bih priopćio bilo otkrivenje, bilo spoznanje, bilo proroštvo, bilo nauk?"},{"v":7,"t":"Ako neživa glazbala, svirala ili citra, ne daju razgovijetna glasa, kako će se razabrati što se to izvodi na svirali ili citri?"},{"v":8,"t":"Ili ako trublja daje nejasan glas, tko će se spremiti na boj?"},{"v":9,"t":"Tako i vi, ako jezikom ne budete jasno zborili, kako će se razabrati što se govori? Govorit ćete u vjetar."},{"v":10,"t":"Toliko, recimo, ima na svijetu vrsta glasova i - nijedan bez značenja."},{"v":11,"t":"Ako dakle ne znam značenja glasa, bit ću sugovorniku tuđinac, a sugovornik tuđinac meni."},{"v":12,"t":"Tako i vi, budući da čeznete za darima Duha, nastojte njima obilovati radi izgrađivanja Crkve."},{"v":13,"t":"Stoga tko govori drugim jezikom, neka se moli da može protumačiti."},{"v":14,"t":"Jer ako se drugim jezikom molim, moj se duh moli, ali um je moj neplodan."},{"v":15,"t":"Što dakle? Molit ću se duhom, molit ću se i umom; pjevat ću hvalospjeve duhom, ali pjevat ću ih i umom."},{"v":16,"t":"Jer ako Boga blagoslivljaš duhom, kako će neupućen reći “Amen” na tvoju zahvalnicu? Ne zna što govoriš."},{"v":17,"t":"Ti doduše lijepo zahvaljuješ, ali se drugi ne izgrađuje."},{"v":18,"t":"Hvala Bogu, ja govorim drugim jezicima većma nego svi vi."},{"v":19,"t":"Ali draže mi je u Crkvi reći pet riječi po svojoj pameti, da i druge poučim, negoli deset tisuća riječi drugim jezikom."},{"v":20,"t":"Braćo, ne budite djeca pameću, nego nejačad pakošću, a zreli pameću!"},{"v":21,"t":"U Zakonu je pisano: Drugim jezicima i drugim usnama govorit ću ovomu narodu pa me ni tako neće poslušati, govori Gospodin."},{"v":22,"t":"Tako drugi jezici nisu znak vjernicima, nego nevjernicima; a prorokovanje vjernicima, ne nevjernicima."},{"v":23,"t":"Ako se dakle skupi sva Crkva zajedno i svi govore drugim jezicima, a uđu neupućeni ili nevjernici, neće li reći da mahnitate?"},{"v":24,"t":"Ako pak svi prorokuju, a uđe koji nevjernik ili neupućen, sve ga prekorava, sve ga osuđuje."},{"v":25,"t":"Tajne se njegova srca očituju te će pasti ničice i pokloniti se Bogu priznajući: Zaista, Bog je u vama."},{"v":26,"t":"Što dakle braćo? Kad se skupite te poneki ima hvalospjev, poneki ima nauk, ima otkrivenje, ima jezik, ima tumačenje - sve neka bude radi izgrađivanja."},{"v":27,"t":"Ako tko govori drugim jezikom - dvojica, najviše trojica, i to jedan za drugim - jedan neka tumači;"},{"v":28,"t":"ako pak ne bi bilo tumača, neka šuti u Crkvi, neka govori sam sebi i Bogu."},{"v":29,"t":"Od proroka pak neka govore dvojica ili trojica, drugi neka rasuđuju."},{"v":30,"t":"Ali ako drugomu uza nj bude što objavljeno, prvi neka šuti."},{"v":31,"t":"A možete jedan po jedan svi prorokovati da svi budu poučeni i svi ohrabreni."},{"v":32,"t":"Proročki su duhovi prorocima podložni"},{"v":33,"t":"jer Bog nije Bog nesklada, nego Bog mira. Kao u svim Crkvama svetih, žene na Sastancima neka šute."},{"v":34,"t":"Nije im dopušteno govoriti, nego neka budu podložne, kako i Zakon govori."},{"v":35,"t":"Žele li što saznati, neka kod kuće pitaju svoje muževe jer ružno je da žena govori na Sastanku."},{"v":36,"t":"Ili zar je riječ Božja od vas proizašla, zar je samo k vama došla?"},{"v":37,"t":"Smatra li tko da je prorok ili duhom obdaren, neka zna: što vam pišem, Gospodnja je zapovijed."},{"v":38,"t":"Tko to ne prizna, ne priznaje se."},{"v":39,"t":"Zato, braćo moja, težite prorokovati i ne priječite da se govori drugim jezicima!"},{"v":40,"t":"A sve neka bude dostojno i uredno."}]},"15":{"fa":[{"v":1,"t":"الان‌ای برادران، شما را از انجیلی که به شما بشارت دادم اعلام می‌نمایم که آن را هم پذیرفتید و در آن هم قایم می‌باشید،"},{"v":2,"t":"وبوسیله آن نیز نجات می‌یابید، به شرطی که آن کلامی را که به شما بشارت دادم، محکم نگاه دارید والا عبث ایمان آوردید."},{"v":3,"t":"زیرا که اول به شما سپردم، آنچه نیز یافتم که مسیح برحسب کتب در راه گناهان ما مرد،"},{"v":4,"t":"و اینکه مدفون شد ودر روز سوم برحسب کتب برخاست؛"},{"v":5,"t":"و اینکه به کیفا ظاهر شد و بعد از آن به آن دوازده،"},{"v":6,"t":"و پس ازآن به زیاده از پانصد برادر یک بار ظاهر شد که بیشتر از ایشان تا امروز باقی هستند اما بعضی خوابیده‌اند."},{"v":7,"t":"از آن پس به یعقوب ظاهر شد و بعدبه جمیع رسولان."},{"v":8,"t":"و آخر همه بر من مثل طفل سقطشده ظاهر گردید."},{"v":9,"t":"زیرا من کهترین رسولان هستم و لایق نیستم که به رسول خوانده شوم، چونکه برکلیسای خدا جفا می‌رسانیدم."},{"v":10,"t":"لیکن به فیض خدا آنچه هستم هستم و فیض او که بر من بود باطل نگشت، بلکه بیش از همه ایشان مشقت کشیدم، اما نه من بلکه فیض خدا که با من بود."},{"v":11,"t":"پس خواه من و خواه ایشان بدین طریق وعظمی کنیم و به اینطور ایمان آوردید."},{"v":12,"t":"لیکن اگر به مسیح وعظ می‌شود که ازمردگان برخاست، چون است که بعضی از شمامی گویند که قیامت مردگان نیست؟"},{"v":13,"t":"اما اگرمردگان را قیامت نیست، مسیح نیز برنخاسته است."},{"v":14,"t":"و اگر مسیح برنخاست، باطل است وعظما و باطل است نیز ایمان شما."},{"v":15,"t":"و شهود کذبه نیز برای خدا شدیم، زیرا درباره خدا شهادت دادیم که مسیح را برخیزانید، و حال آنکه او رابرنخیزانید در صورتی که مردگان برنمی خیزند."},{"v":16,"t":"زیرا هرگاه مردگان برنمی خیزند، مسیح نیزبرنخاسته است."},{"v":17,"t":"اما هرگاه مسیح برنخاسته است، ایمان شما باطل است و شما تاکنون درگناهان خود هستید،"},{"v":18,"t":"بلکه آنانی هم که درمسیح خوابیده‌اند هلاک شدند."},{"v":19,"t":"اگر فقط در این جهان در مسیح امیدواریم، از جمیع مردم بدبخت تریم."},{"v":20,"t":"لیکن بالفعل مسیح از مردگان برخاسته ونوبر خوابیدگان شده است."},{"v":21,"t":"زیرا چنانکه به انسان موت آمد، به انسان نیز قیامت مردگان شد."},{"v":22,"t":"و چنانکه در آدم همه می‌میرند در مسیح نیزهمه زنده خواهند گشت."},{"v":23,"t":"لیکن هرکس به رتبه خود؛ مسیح نوبر است و بعد آنانی که در وقت آمدن او از آن مسیح می‌باشند."},{"v":24,"t":"و بعد از آن انتها است وقتی که ملکوت را به خدا و پدر سپارد. و در آن زمان تمام ریاست و تمام قدرت و قوت را نابود خواهد گردانید."},{"v":25,"t":"زیرا مادامی که همه دشمنان را زیر پایهای خود ننهد، می‌باید اوسلطنت بنماید."},{"v":26,"t":"دشمن آخر که نابود می‌شود، موت است."},{"v":27,"t":"زیرا «همه‌چیز را زیر پایهای وی انداخته است». اما چون می‌گوید که «همه‌چیز رازیر انداخته است»، واضح است که او که همه رازیر او انداخت مستثنی است."},{"v":28,"t":"اما زمانی که همه مطیع وی شده باشند، آنگاه خود پسر هم مطیع خواهد شد او را که همه‌چیز را مطیع وی گردانید، تا آنکه خدا کل در کل باشد."},{"v":29,"t":"والا آنانی که برای مردگان تعمید می‌یابندچکنند؟ هرگاه مردگان مطلق برنمی خیزند، پس چرا برای ایشان تعمید می‌گیرند؟"},{"v":30,"t":"و ما نیز چراهر ساعت خود را در خطر می‌اندازیم؟"},{"v":31,"t":"به آن فخری درباره شما که مرا در خداوند ما مسیح عیسی هست قسم، که هرروزه مرا مردنی است."},{"v":32,"t":"چون بطور انسان در افسس با وحوش جنگ کردم، مرا چه سود است؟ اگر مردگان برنمی خیزند، بخوریم و بیاشامیم چون فردامی میریم."},{"v":33,"t":"فریفته مشوید معاشرات بد، اخلاق حسنه را فاسد می‌سازد."},{"v":34,"t":"برای عدالت بیدارشده، گناه مکنید زیرا بعضی معرفت خدا راندارند. برای انفعال شما می‌گویم."},{"v":35,"t":"اما اگر کسی گوید: «مردگان چگونه برمی خیزند و به کدام بدن می‌آیند؟»،"},{"v":36,"t":"‌ای احمق آنچه تو می‌کاری زنده نمی گردد جز آنکه بمیرد."},{"v":37,"t":"و آنچه می‌کاری، نه آن جسمی را که خواهد شد می‌کاری، بلکه دانه‌ای مجرد خواه ازگندم و یا از دانه های دیگر."},{"v":38,"t":"لیکن خدا برحسب اراده خود، آن را جسمی می‌دهد و به هر یکی ازتخمها جسم خودش را."},{"v":39,"t":"هر گوشت از یک نوع گوشت نیست، بلکه گوشت انسان، دیگر است وگوشت بهایم، دیگر و گوشت مرغان، دیگر وگوشت ماهیان، دیگر."},{"v":40,"t":"و جسمهای آسمانی هست و جسمهای زمینی نیز، لیکن‌شان آسمانی‌ها، دیگر و‌شان زمینی‌ها، دیگر است،"},{"v":41,"t":"و‌شان آفتاب دیگر و‌شان ماه دیگر و‌شان ستارگان، دیگر، زیرا که ستاره از ستاره در‌شان، فرق دارد."},{"v":42,"t":"به همین نهج است نیز قیامت مردگان. درفساد کاشته می‌شود، و در بی‌فسادی برمی خیزد؛"},{"v":43,"t":"در ذلت کاشته می‌گردد و در جلال برمی خیزد؛ در ضعف کاشته می‌شود و در قوت برمی خیزد؛"},{"v":44,"t":"جسم نفسانی کاشته می‌شود و جسم روحانی برمی خیزد. اگر جسم نفسانی هست، هرآینه روحانی نیز هست."},{"v":45,"t":"و همچنین نیز مکتوب است که انسان اول یعنی آدم نفس زنده گشت، اماآدم آخر روح حیات‌بخش شد."},{"v":46,"t":"لیکن روحانی مقدم نبود بلکه نفسانی و بعد از آن روحانی."},{"v":47,"t":"انسان اول از زمین است خاکی؛ انسان دوم خداوند است از آسمان."},{"v":48,"t":"چنانکه خاکی است، خاکیان نیز چنان هستند و چنانکه آسمانی است آسمانی‌ها همچنان می‌باشند."},{"v":49,"t":"و چنانکه صورت خاکی را گرفتیم، صورت آسمانی را نیزخواهیم گرفت."},{"v":50,"t":"لیکن‌ای برادران این را می‌گویم که گوشت و خون نمی تواند وارث ملکوت خدا شود و فاسدوارث بی‌فسادی نیز نمی شود."},{"v":51,"t":"همانا به شماسری می‌گویم که همه نخواهیم خوابید، لیکن همه متبدل خواهیم شد."},{"v":52,"t":"در لحظه‌ای، درطرفه العینی، به مجرد نواختن صور اخیر، زیراکرنا صدا خواهد داد، و مردگان، بی‌فساد خواهندبرخاست و ما متبدل خواهیم شد."},{"v":53,"t":"زیرا که می‌باید این فاسد بی‌فسادی را بپوشد و این فانی به بقا آراسته گردد."},{"v":54,"t":"اما چون این فاسد بی‌فسادی را پوشید و این فانی به بقا آراسته شد، آنگاه این کلامی که مکتوب است به انجام خواهد رسید که «مرگ در ظفر بلعیده شده است."},{"v":55,"t":"‌ای موت نیش تو کجا است و‌ای گور ظفر تو کجا؟»"},{"v":56,"t":"نیش موت گناه است و قوت گناه، شریعت."},{"v":57,"t":"لیکن شکر خدا راست که ما را بواسطه خداوند ماعیسی مسیح ظفر می‌دهد."},{"v":58,"t":"بنابراین‌ای برادران حبیب من پایدار وبی تشویش شده، پیوسته در عمل خداوندبیفزایید، چون می‌دانید که زحمت شما درخداوند باطل نیست."}],"en":[{"v":1,"t":"Now I declare to you, brothers, the Good News which I preached to you, which also you received, in which you also stand,"},{"v":2,"t":"by which also you are saved, if you hold firmly the word which I preached to you—unless you believed in vain."},{"v":3,"t":"For I delivered to you first of all that which I also received: that Christ died for our sins according to the Scriptures,"},{"v":4,"t":"that he was buried, that he was raised on the third day according to the Scriptures,"},{"v":5,"t":"and that he appeared to Cephas, then to the twelve."},{"v":6,"t":"Then he appeared to over five hundred brothers at once, most of whom remain until now, but some have also fallen asleep."},{"v":7,"t":"Then he appeared to James, then to all the apostles,"},{"v":8,"t":"and last of all, as to the child born at the wrong time, he appeared to me also."},{"v":9,"t":"For I am the least of the apostles, who is not worthy to be called an apostle, because I persecuted the assembly of God."},{"v":10,"t":"But by the grace of God I am what I am. His grace which was given to me was not futile, but I worked more than all of them; yet not I, but the grace of God which was with me."},{"v":11,"t":"Whether then it is I or they, so we preach, and so you believed."},{"v":12,"t":"Now if Christ is preached, that he has been raised from the dead, how do some among you say that there is no resurrection of the dead?"},{"v":13,"t":"But if there is no resurrection of the dead, neither has Christ been raised."},{"v":14,"t":"If Christ has not been raised, then our preaching is in vain and your faith also is in vain."},{"v":15,"t":"Yes, we are also found false witnesses of God, because we testified about God that he raised up Christ, whom he didn’t raise up if it is true that the dead are not raised."},{"v":16,"t":"For if the dead aren’t raised, neither has Christ been raised."},{"v":17,"t":"If Christ has not been raised, your faith is vain; you are still in your sins."},{"v":18,"t":"Then they also who are fallen asleep in Christ have perished."},{"v":19,"t":"If we have only hoped in Christ in this life, we are of all men most pitiable."},{"v":20,"t":"But now Christ has been raised from the dead. He became the first fruit of those who are asleep."},{"v":21,"t":"For since death came by man, the resurrection of the dead also came by man."},{"v":22,"t":"For as in Adam all die, so also in Christ all will be made alive."},{"v":23,"t":"But each in his own order: Christ the first fruits, then those who are Christ’s at his coming."},{"v":24,"t":"Then the end comes, when he will deliver up the Kingdom to God the Father, when he will have abolished all rule and all authority and power."},{"v":25,"t":"For he must reign until he has put all his enemies under his feet."},{"v":26,"t":"The last enemy that will be abolished is death."},{"v":27,"t":"For, “He put all things in subjection under his feet.” But when he says, “All things are put in subjection”, it is evident that he is excepted who subjected all things to him."},{"v":28,"t":"When all things have been subjected to him, then the Son will also himself be subjected to him who subjected all things to him, that God may be all in all."},{"v":29,"t":"Or else what will they do who are baptized for the dead? If the dead aren’t raised at all, why then are they baptized for the dead?"},{"v":30,"t":"Why do we also stand in jeopardy every hour?"},{"v":31,"t":"I affirm, by the boasting in you which I have in Christ Jesus our Lord, I die daily."},{"v":32,"t":"If I fought with animals at Ephesus for human purposes, what does it profit me? If the dead are not raised, then “let’s eat and drink, for tomorrow we die.”"},{"v":33,"t":"Don’t be deceived! “Evil companionships corrupt good morals.”"},{"v":34,"t":"Wake up righteously and don’t sin, for some have no knowledge of God. I say this to your shame."},{"v":35,"t":"But someone will say, “How are the dead raised?” and, “With what kind of body do they come?”"},{"v":36,"t":"You foolish one, that which you yourself sow is not made alive unless it dies."},{"v":37,"t":"That which you sow, you don’t sow the body that will be, but a bare grain, maybe of wheat, or of some other kind."},{"v":38,"t":"But God gives it a body even as it pleased him, and to each seed a body of its own."},{"v":39,"t":"All flesh is not the same flesh, but there is one flesh of men, another flesh of animals, another of fish, and another of birds."},{"v":40,"t":"There are also celestial bodies and terrestrial bodies; but the glory of the celestial differs from that of the terrestrial."},{"v":41,"t":"There is one glory of the sun, another glory of the moon, and another glory of the stars; for one star differs from another star in glory."},{"v":42,"t":"So also is the resurrection of the dead. The body is sown perishable; it is raised imperishable."},{"v":43,"t":"It is sown in dishonor; it is raised in glory. It is sown in weakness; it is raised in power."},{"v":44,"t":"It is sown a natural body; it is raised a spiritual body. There is a natural body and there is also a spiritual body."},{"v":45,"t":"So also it is written, “The first man Adam became a living soul.” The last Adam became a life-giving spirit."},{"v":46,"t":"However, that which is spiritual isn’t first, but that which is natural, then that which is spiritual."},{"v":47,"t":"The first man is of the earth, made of dust. The second man is the Lord from heaven."},{"v":48,"t":"As is the one made of dust, such are those who are also made of dust; and as is the heavenly, such are they also that are heavenly."},{"v":49,"t":"As we have borne the image of those made of dust, let’s also bear the image of the heavenly."},{"v":50,"t":"Now I say this, brothers, that flesh and blood can’t inherit God’s Kingdom; neither does the perishable inherit imperishable."},{"v":51,"t":"Behold, I tell you a mystery. We will not all sleep, but we will all be changed,"},{"v":52,"t":"in a moment, in the twinkling of an eye, at the last trumpet. For the trumpet will sound and the dead will be raised incorruptible, and we will be changed."},{"v":53,"t":"For this perishable body must become imperishable, and this mortal must put on immortality."},{"v":54,"t":"But when this perishable body will have become imperishable, and this mortal will have put on immortality, then what is written will happen: “Death is swallowed up in victory.”"},{"v":55,"t":"“Death, where is your sting? Hades, where is your victory?”"},{"v":56,"t":"The sting of death is sin, and the power of sin is the law."},{"v":57,"t":"But thanks be to God, who gives us the victory through our Lord Jesus Christ."},{"v":58,"t":"Therefore, my beloved brothers, be steadfast, immovable, always abounding in the Lord’s work, because you know that your labor is not in vain in the Lord."}],"hr":[{"v":1,"t":"Dozivljem vam, braćo, u pamet evanđelje koje vam navijestih, koje primiste, u kome stojite,"},{"v":2,"t":"po kojem se spasavate, ako držite što sam vam navijestio; osim ako uzalud povjerovaste."},{"v":3,"t":"Doista, predadoh vam ponajprije što i primih: Krist umrije za grijehe naše po Pismima;"},{"v":4,"t":"bi pokopan i uskrišen treći dan po Pismima;"},{"v":5,"t":"ukaza se Kefi, zatim dvanaestorici."},{"v":6,"t":"Potom se ukaza braći, kojih bijaše više od pet stotina zajedno; većina ih još i sada živi, a neki usnuše."},{"v":7,"t":"Zatim se ukaza Jakovu, onda svim apostolima."},{"v":8,"t":"Najposlije, kao nedonoščetu, ukaza se i meni."},{"v":9,"t":"Da, ja sam najmanji među apostolima i nisam dostojan zvati se apostolom jer sam progonio Crkvu Božju."},{"v":10,"t":"Ali milošću Božjom jesam što jesam i njegova milost prema meni ne bijaše zaludna; štoviše, trudio sam se više nego svi oni - ali ne ja, nego milost Božja sa mnom."},{"v":11,"t":"Ili dakle ja ili oni: tako propovijedamo, tako vjerujete."},{"v":12,"t":"No ako se propovijeda da je Krist od mrtvih uskrsnuo, kako neki među vama govore da nema uskrsnuća mrtvih?"},{"v":13,"t":"Ako nema uskrsnuća mrtvih, ni Krist nije uskrsnuo."},{"v":14,"t":"Ako pak Krist nije uskrsnuo, uzalud je doista propovijedanje naše, uzalud i vjera vaša."},{"v":15,"t":"Zatekli bismo se i kao lažni svjedoci Božji što posvjedočismo protiv Boga: da je uskrisio Krista, kojega nije uskrisio, ako doista mrtvi ne uskršavaju."},{"v":16,"t":"Jer ako mrtvi ne uskršavaju, ni Krist nije uskrsnuo."},{"v":17,"t":"A ako Krist nije uskrsnuo, uzaludna je vjera vaša, još ste u grijesima."},{"v":18,"t":"Onda i oni koji usnuše u Kristu, propadoše."},{"v":19,"t":"Ako se samo u ovom životu u Krista ufamo, najbjedniji smo od svih ljudi."},{"v":20,"t":"Ali sada: Krist uskrsnu od mrtvih, prvina usnulih!"},{"v":21,"t":"Doista po čovjeku smrt, po Čovjeku i uskrsnuće od mrtvih!"},{"v":22,"t":"Jer kao što u Adamu svi umiru, tako će i u Kristu svi biti oživljeni."},{"v":23,"t":"Ali svatko u svom redu: prvina Krist, a zatim koji su Kristovi, o njegovu Dolasku;"},{"v":24,"t":"potom - svršetak, kad preda kraljevstvo Bogu i Ocu, pošto obeskrijepi svako Vrhovništvo, svaku Vlast i Silu."},{"v":25,"t":"Doista, on treba da kraljuje dok ne podloži sve neprijatelje pod noge svoje."},{"v":26,"t":"Kao posljednji neprijatelj bit će obeskrijepljena Smrt"},{"v":27,"t":"jer sve podloži nogama njegovim. A kad veli: Sve je podloženo, jasno - sve osim Onoga koji mu je sve podložio."},{"v":28,"t":"I kad mu sve bude podloženo, tada će se i on sam, Sin, podložiti Onomu koji je njemu sve podložio da Bog bude sve u svemu."},{"v":29,"t":"Što onda čine oni koji se krste za mrtve? Ako mrtvi uopće ne uskršavaju, što se krste za njih?"},{"v":30,"t":"Što se onda i mi svaki čas izlažemo pogiblima?"},{"v":31,"t":"Dan za danom umirem, tako mi slave vaše, braćo, koju imam u Kristu Isusu, Gospodinu našem!"},{"v":32,"t":"Ako sam se po ljudsku borio sa zvijerima u Efezu, kakva mi korist? Ako mrtvi ne uskršavaju, jedimo i pijmo jer sutra nam je umrijeti."},{"v":33,"t":"Ne varajte se: “Zli razgovori kvare dobre običaje.”"},{"v":34,"t":"Otrijeznite se kako valja i ne griješite jer neki, na sramotu vam kažem, ne znaju za Boga."},{"v":35,"t":"Ali reći će netko: Kako uskršavaju mrtvi? I s kakvim li će tijelom doći?"},{"v":36,"t":"Bezumniče! Što siješ, ne oživljuje ako ne umre."},{"v":37,"t":"I što siješ, ne siješ tijelo buduće, već golo zrno, pšenice - recimo - ili čega drugoga."},{"v":38,"t":"A Bog mu daje tijelo kakvo hoće, i to svakom sjemenu svoje tijelo."},{"v":39,"t":"Nije svako tijelo isto tijelo; drugo je tijelo čovječje, drugo tijelo stoke, drugo tijelo ptičje, a drugo riblje."},{"v":40,"t":"Ima tjelesa nebeskih i tjelesa zemaljskih, ali drugi je sjaj nebeskih, a drugi zemaljskih."},{"v":41,"t":"Drugi je sjaj sunca, drugi sjaj mjeseca i drugi sjaj zvijezda; jer zvijezda se od zvijezde razlikuje u sjaju."},{"v":42,"t":"Tako i uskrsnuće mrtvih: sije se u raspadljivosti, uskršava u neraspadljivosti;"},{"v":43,"t":"sije se u sramoti, uskršava u slavi; sije se u slabosti, uskršava u snazi;"},{"v":44,"t":"sije se tijelo naravno, uskršava tijelo duhovno. Ako ima tijelo naravno, ima i duhovno."},{"v":45,"t":"Tako je i pisano: Prvi čovjek, Adam, postade živa duša, posljednji Adam - duh životvorni."},{"v":46,"t":"Ali ne bi najprije duhovno, nego naravno pa onda duhovno."},{"v":47,"t":"Prvi je čovjek od zemlje, zemljan; drugi čovjek - s neba."},{"v":48,"t":"Kakav je zemljani takvi su i zemljani, a kakav je nebeski takvi su i nebeski."},{"v":49,"t":"I kao što smo nosili sliku zemljanoga, nosit ćemo i sliku nebeskoga."},{"v":50,"t":"A ovo, braćo, tvrdim: tijelo i krv ne mogu baštiniti kraljevstva Božjega i raspadljivost ne baštini neraspadljivosti."},{"v":51,"t":"Evo otajstvo vam kazujem: svi doduše nećemo usnuti, ali svi ćemo se izmijeniti."},{"v":52,"t":"Odjednom, u tren oka, na posljednju trublju - jer zatrubit će - i mrtvi će uskrsnuti neraspadljivi i mi ćemo se izmijeniti."},{"v":53,"t":"Jer ovo raspadljivo treba da se obuče u neraspadljivost i ovo smrtno da se obuče u besmrtnost."},{"v":54,"t":"A kad se ovo raspadljivo obuče u neraspadljivost i ovo smrtno obuče u besmrtnost, tada će se obistiniti riječ napisana: Pobjeda iskapi smrt."},{"v":55,"t":"Gdje je, smrti, pobjeda tvoja? Gdje je, smrti, žalac tvoj?"},{"v":56,"t":"Žalac je smrti grijeh, snaga je grijeha Zakon."},{"v":57,"t":"A hvala Bogu koji nam daje pobjedu po Gospodinu našem Isusu Kristu!"},{"v":58,"t":"Tako, braćo moja ljubljena, budite postojani, nepokolebljivi, i obilujte svagda u djelu Gospodnjem znajući da trud vaš nije neplodan u Gospodinu."}]},"16":{"fa":[{"v":1,"t":"اما درباره جمع کردن زکات برای مقدسین، چنانکه به کلیساهای غلاطیه فرمودم، شما نیز همچنین کنید."},{"v":2,"t":"در روز اول هفته، هر یکی از شما بحسب نعمتی که یافته باشد، نزد خود ذخیره کرده، بگذارد تا در وقت آمدن من زحمت جمع کردن نباشد."},{"v":3,"t":"و چون برسم، آنانی را که اختیار کنید با مکتوبها خواهم فرستاد تا احسان شما را به اورشلیم ببرند."},{"v":4,"t":"و اگرمصلحت باشد که من نیز بروم، همراه من خواهندآمد."},{"v":5,"t":"و چون از مکادونیه عبور کنم، به نزد شماخواهم آمد، زیرا که از مکادنیه عبور می‌کنم،"},{"v":6,"t":"واحتمال دارد که نزد شما بمانم بلکه زمستان را نیزبسر برم تا هرجایی که بروم، شما مرا مشایعت کنید."},{"v":7,"t":"زیرا که الان اراده ندارم در بین راه شما راملاقات کنم، چونکه امیدوارم مدتی با شما توقف نمایم، اگر خداوند اجازت دهد."},{"v":8,"t":"لیکن من تاپنطیکاست در افسس خواهم ماند،"},{"v":9,"t":"زیرا که دروازه بزرگ و کارساز برای من باز شد و معاندین، بسیارند."},{"v":10,"t":"لیکن اگر تیموتاوس آید، آگاه باشیدکه نزد شما بی‌ترس باشد، زیرا که در کار خداوندمشغول است چنانکه من نیز هستم."},{"v":11,"t":"لهذاهیچ‌کس او را حقیر نشمارد، بلکه او را به سلامتی مشایعت کنید تا نزد من آید زیرا که او را با برادران انتظار می‌کشم."},{"v":12,"t":"اما درباره اپلس برادر، از اوبسیار درخواست نمودم که با برادران به نزد شمابیاید، لیکن هرگز رضا نداد که الحال بیاید ولی چون فرصت یابد خواهد آمد."},{"v":13,"t":"بیدار شوید، در ایمان استوار باشید و مردان باشید و زورآور شوید."},{"v":14,"t":"جمیع کارهای شما با محبت باشد."},{"v":15,"t":"و‌ای برادران به شماالتماس دارم (شما خانواده استیفان را می‌شناسیدکه نوبر اخائیه هستند و خویشتن را به خدمت مقدسین سپرده اند)،"},{"v":16,"t":"تا شما نیز چنین اشخاص را اطاعت کنید و هرکس را که در کار و زحمت شریک باشد."},{"v":17,"t":"و از آمدن استفان و فرتوناتس واخائیکوس مرا شادی رخ نمود زیرا که آنچه ازجانب شما ناتمام بود، ایشان تمام کردند."},{"v":18,"t":"چونکه روح من و شما را تازه کردند. پس چنین اشخاص را بشناسید."},{"v":19,"t":"کلیساهای آسیا به شما سلام می‌رسانند واکیلا و پرسکلا با کلیسایی که در خانه ایشانند، به شما سلام بسیار در خداوند می‌رسانند."},{"v":20,"t":"همه برادران شما را سلام می‌رسانند. یکدیگر را به بوسه مقدسانه سلام رسانید."},{"v":21,"t":"من پولس ازدست خود سلام می‌رسانم."},{"v":22,"t":"اگر کسی عیسی مسیح خداوند را دوست ندارد، اناتیما باد. ماران اتا."},{"v":23,"t":"فیض عیسی مسیح خداوند با شما باد."},{"v":24,"t":"محبت من با همه شما در مسیح عیسی باد، آمین."}],"en":[{"v":1,"t":"Now concerning the collection for the saints: as I commanded the assemblies of Galatia, you do likewise."},{"v":2,"t":"On the first day of every week, let each one of you save as he may prosper, that no collections are made when I come."},{"v":3,"t":"When I arrive, I will send whoever you approve with letters to carry your gracious gift to Jerusalem."},{"v":4,"t":"If it is appropriate for me to go also, they will go with me."},{"v":5,"t":"I will come to you when I have passed through Macedonia, for I am passing through Macedonia."},{"v":6,"t":"But with you it may be that I will stay with you, or even winter with you, that you may send me on my journey wherever I go."},{"v":7,"t":"For I do not wish to see you now in passing, but I hope to stay a while with you, if the Lord permits."},{"v":8,"t":"But I will stay at Ephesus until Pentecost,"},{"v":9,"t":"for a great and effective door has opened to me, and there are many adversaries."},{"v":10,"t":"Now if Timothy comes, see that he is with you without fear, for he does the work of the Lord, as I also do."},{"v":11,"t":"Therefore let no one despise him. But set him forward on his journey in peace, that he may come to me; for I expect him with the brothers."},{"v":12,"t":"Now concerning Apollos the brother, I strongly urged him to come to you with the brothers, but it was not at all his desire to come now; but he will come when he has an opportunity."},{"v":13,"t":"Watch! Stand firm in the faith! Be courageous! Be strong!"},{"v":14,"t":"Let all that you do be done in love."},{"v":15,"t":"Now I beg you, brothers—you know the house of Stephanas, that it is the first fruits of Achaia, and that they have set themselves to serve the saints—"},{"v":16,"t":"that you also be in subjection to such, and to everyone who helps in the work and labors."},{"v":17,"t":"I rejoice at the coming of Stephanas, Fortunatus, and Achaicus; for that which was lacking on your part, they supplied."},{"v":18,"t":"For they refreshed my spirit and yours. Therefore acknowledge those who are like that."},{"v":19,"t":"The assemblies of Asia greet you. Aquila and Priscilla greet you warmly in the Lord, together with the assembly that is in their house."},{"v":20,"t":"All the brothers greet you. Greet one another with a holy kiss."},{"v":21,"t":"This greeting is by me, Paul, with my own hand."},{"v":22,"t":"If any man doesn’t love the Lord Jesus Christ, let him be cursed. Come, Lord!"},{"v":23,"t":"The grace of the Lord Jesus Christ be with you."},{"v":24,"t":"My love to all of you in Christ Jesus. Amen."}],"hr":[{"v":1,"t":"U pogledu sabiranja za svete, i vi činite kako odredih crkvama galacijskim."},{"v":2,"t":"Svakoga prvog dana u tjednu neka svaki od vas kod sebe na stranu stavlja i skuplja što uzmogne da se ne sabire istom kada dođem."},{"v":3,"t":"A kada dođem, poslat ću s preporučnicom one koje odaberete da odnesu vašu ljubav u Jeruzalem."},{"v":4,"t":"Bude li vrijedno da i ja pođem, poći će sa mnom."},{"v":5,"t":"A k vama ću doći kad prođem Makedoniju; Makedonijom ću samo proći,"},{"v":6,"t":"a kod vas ću se možda zadržati ili čak zimovati da me otpratite kamo god pođem."},{"v":7,"t":"Ne bih vas doista htio tek na prolazu vidjeti jer se nadam neko vrijeme proboraviti kod vas, dopusti li Gospodin."},{"v":8,"t":"U Efezu ću ostati do Pedesetnice"},{"v":9,"t":"jer vrata mi se otvoriše velika i uspješna, a protivnika mnogo."},{"v":10,"t":"Ako dođe Timotej, gledajte da bude kod vas bez bojazni jer radi djelo Gospodnje kao i ja."},{"v":11,"t":"Neka ga dakle nitko ne prezre. A ispratite ga u miru da dođe k meni jer ga s braćom iščekujem."},{"v":12,"t":"A što se tiče brata Apolona: mnogo sam ga nagovarao da ode k vama s braćom. I nikako mu ne bijaše s voljom da sada dođe, no doći će kad mu bude zgodno."},{"v":13,"t":"Bdijte postojani u vjeri, muževni budite, čvrsti."},{"v":14,"t":"Sve vaše neka bude u ljubavi!"},{"v":15,"t":"Zaklinjem vas, braćo - znate dom Stefanin, da je prvina Ahaje i da se posvetiše posluživanju svetih -"},{"v":16,"t":"da se i vi pokoravate takvima i svakomu tko surađuje i trudi se."},{"v":17,"t":"Radujem se s dolaska Stefanina i Fortunatova i Ahajikova jer oni nadoknadiše vašu nenazočnost:"},{"v":18,"t":"umiriše duh moj i vaš. Cijenite dakle takve."},{"v":19,"t":"Pozdravljaju vas crkve azijske. Pozdravljaju vas mnogo u Gospodinu Akvila i Priska zajedno s Crkvom u njihovu domu."},{"v":20,"t":"Pozdravljaju vas sva braća. Pozdravite jedni druge cjelovom svetim."},{"v":21,"t":"Pozdrav mojom rukom, Pavlovom."},{"v":22,"t":"Ako tko ne ljubi Gospodina, neka bude proklet. Marana tha!"},{"v":23,"t":"Milost Gospodina Isusa s vama!"},{"v":24,"t":"Ljubav moja sa svima vama u Kristu Isusu!"}]}},"2CO":{"1":{"fa":[{"v":1,"t":"پولس به اراده خدا رسول عیسی مسیح وتیموتاوس برادر، به کلیسای خدا که در قرنتس می‌باشد با همه مقدسینی که در تمام اخائیه هستند،"},{"v":2,"t":"فیض و سلامتی از پدر ما خدا و عیسی مسیح خداوند به شما باد."},{"v":3,"t":"متبارک باد خدا و پدر خداوند ما عیسی مسیح که پدر رحمتها و خدای جمیع تسلیات است،"},{"v":4,"t":"که ما را در هر تنگی ما تسلی می‌دهد تا مابتوانیم دیگران را در هر مصیبتی که باشد تسلی نماییم، به آن تسلی که خود از خدا یافته‌ایم."},{"v":5,"t":"زیرا به اندازه‌ای که دردهای مسیح در ما زیاده شود، به همین قسم تسلی ما نیز بوسیله مسیح می‌افزاید."},{"v":6,"t":"اما خواه زحمت کشیم، این است برای تسلی و نجات شما، و خواه تسلی پذیریم این هم بجهت تسلی و نجات شما است که میسرمی شود از صبر داشتن در همین دردهایی که ما هم می‌بینیم."},{"v":7,"t":"و امید ما برای شما استوار می‌شودزیرا می‌دانیم که چنانکه شما شریک دردهاهستید، همچنین شریک تسلی نیز خواهید بود."},{"v":8,"t":"زیرا‌ای برادران نمی خواهیم شما بی‌خبرباشید از تنگی‌ای که در آسیا به ما عارض گردید که بینهایت و فوق از طاقت بار کشیدیم، بحدی که از جان هم مایوس شدیم."},{"v":9,"t":"لکن در خود فتوای موت داشتیم تا بر خود توکل نکنیم، بلکه بر خداکه مردگان را برمی خیزاند،"},{"v":10,"t":"که ما را از چنین موت رهانید و می‌رهاند و به او امیدواریم که بعداز این هم خواهد رهانید."},{"v":11,"t":"و شما نیز به دعا درحق ما اعانت می‌کنید تا آنکه برای آن نعمتی که ازاشخاص بسیاری به ما رسید، شکرگزاری هم بجهت ما از بسیاری به‌جا آورده شود."},{"v":12,"t":"زیرا که فخر ما این است یعنی شهادت ضمیر ما که به قدوسیت و اخلاص خدایی، نه به حکمت جسمانی، بلکه به فیض الهی در جهان رفتار نمودیم و خصوص نسبت به شما."},{"v":13,"t":"زیراچیزی به شما نمی نویسیم مگر آنچه می‌خوانید وبه آن اعتراف می‌کنید و امیدوارم که تا به آخراعتراف هم خواهید کرد."},{"v":14,"t":"چنانکه به مافی الجمله اعتراف گردید که محل فخر شماهستیم، چنانکه شما نیز ما را می‌باشید در روزعیسی خداوند."},{"v":15,"t":"و بدین اعتماد قبل از این خواستم به نزدشما آیم تا نعمتی دیگر بیابید،"},{"v":16,"t":"و از راه شما به مکادونیه بروم و باز از مکادونیه نزد شما بیایم و شما مرا به سوی یهودیه مشایعت کنید."},{"v":17,"t":"پس چون این را خواستم، آیا سهل انگاری کردم یاعزیمت من عزیمت بشری باشد تا آنکه به نزد من بلی بلی و نی نی باشد."},{"v":18,"t":"لیکن خدا امین است که سخن ما با شما بلی و نی نیست."},{"v":19,"t":"زیرا که پسرخدا عیسی مسیح که ما یعنی من و سلوانس وتیموتاوس در میان شما به وی موعظه کردیم، بلی و نی نشد بلکه در او بلی شده است."},{"v":20,"t":"زیراچندان‌که وعده های خدا است، همه در او بلی واز این جهت در او امین است تا خدا از ما تمجیدیابد."},{"v":21,"t":"اما او که ما را با شما در مسیح استوارمی گرداند و ما را مسح نموده است، خداست."},{"v":22,"t":"که او نیز ما را مهر نموده و بیعانه روح را دردلهای ما عطا کرده است."},{"v":23,"t":"لیکن من خدا را بر جان خود شاهدمی خوانم که برای شفقت بر شما تا بحال به قرنتس نیامدم،"},{"v":24,"t":"نه آنکه بر ایمان شما حکم کرده باشیم بلکه شادی شما را مددکار هستیم زیرا که به ایمان قایم هستید."}],"en":[{"v":1,"t":"Paul, an apostle of Christ Jesus through the will of God, and Timothy our brother, to the assembly of God which is at Corinth, with all the saints who are in the whole of Achaia:"},{"v":2,"t":"Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":3,"t":"Blessed be the God and Father of our Lord Jesus Christ, the Father of mercies and God of all comfort,"},{"v":4,"t":"who comforts us in all our affliction, that we may be able to comfort those who are in any affliction, through the comfort with which we ourselves are comforted by God."},{"v":5,"t":"For as the sufferings of Christ abound to us, even so our comfort also abounds through Christ."},{"v":6,"t":"But if we are afflicted, it is for your comfort and salvation. If we are comforted, it is for your comfort, which produces in you the patient enduring of the same sufferings which we also suffer."},{"v":7,"t":"Our hope for you is steadfast, knowing that, since you are partakers of the sufferings, so you are also of the comfort."},{"v":8,"t":"For we don’t desire to have you uninformed, brothers, concerning our affliction which happened to us in Asia: that we were weighed down exceedingly, beyond our power, so much that we despaired even of life."},{"v":9,"t":"Yes, we ourselves have had the sentence of death within ourselves, that we should not trust in ourselves, but in God who raises the dead,"},{"v":10,"t":"who delivered us out of so great a death, and does deliver, on whom we have set our hope that he will also still deliver us,"},{"v":11,"t":"you also helping together on our behalf by your supplication; that, for the gift given to us by means of many, thanks may be given by many persons on your behalf."},{"v":12,"t":"For our boasting is this: the testimony of our conscience that in holiness and sincerity of God, not in fleshly wisdom but in the grace of God, we behaved ourselves in the world, and more abundantly toward you."},{"v":13,"t":"For we write no other things to you than what you read or even acknowledge, and I hope you will acknowledge to the end—"},{"v":14,"t":"as also you acknowledged us in part—that we are your boasting, even as you also are ours, in the day of our Lord Jesus."},{"v":15,"t":"In this confidence, I was determined to come first to you, that you might have a second benefit,"},{"v":16,"t":"and by you to pass into Macedonia, and again from Macedonia to come to you, and to be sent forward by you on my journey to Judea."},{"v":17,"t":"When I therefore planned this, did I show fickleness? Or the things that I plan, do I plan according to the flesh, that with me there should be the “Yes, yes” and the “No, no?”"},{"v":18,"t":"But as God is faithful, our word toward you was not “Yes and no.”"},{"v":19,"t":"For the Son of God, Jesus Christ, who was preached among you by us—by me, Silvanus, and Timothy—was not “Yes and no,” but in him is “Yes.”"},{"v":20,"t":"For however many are the promises of God, in him is the “Yes.” Therefore also through him is the “Amen”, to the glory of God through us."},{"v":21,"t":"Now he who establishes us with you in Christ and anointed us is God,"},{"v":22,"t":"who also sealed us and gave us the down payment of the Spirit in our hearts."},{"v":23,"t":"But I call God for a witness to my soul, that to spare you, I didn’t come to Corinth."},{"v":24,"t":"We don’t control your faith, but are fellow workers with you for your joy. For you stand firm in faith."}],"hr":[{"v":1,"t":"Pavao, po volji Božjoj apostol Krista Isusa, i brat Timotej: Crkvi Božjoj u Korintu sa svima svetima u svoj Ahaji."},{"v":2,"t":"Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista!"},{"v":3,"t":"Blagoslovljen Bog i Otac Gospodina našega Isusa Krista, Otac milosrđa i Bog svake utjehe!"},{"v":4,"t":"On nas tješi u svakoj našoj nevolji da bismo i mi sve koji su u nevolji mogli tješiti onom utjehom kojom nas same tješi Bog."},{"v":5,"t":"Jer kao što su obilate patnje Kristove u nama, tako je po Kristu obilata i utjeha naša."},{"v":6,"t":"Bili mi nevoljama pritisnuti za vašu je to utjehu i spasenje; bili utješeni, za vašu je utjehu - djelotvornu: da strpljivo podnesete iste patnje koje i mi podnosimo."},{"v":7,"t":"I tako je stamena nada naša o vama jer znamo: kao što ste zajedničari patnja tako ste i utjehe."},{"v":8,"t":"Ne bismo doista htjeli, braćo, da ne znate za nevolju koja nas je snašla u Aziji. Bijasmo prekomjerno, preko snage, opterećeni te smo već strepili i za život."},{"v":9,"t":"Ali u sebi prihvatismo i smrtnu osudu da se ne bismo uzdali u same sebe, nego u Boga koji uskrisuje mrtve."},{"v":10,"t":"On nas je od takve smrti izbavio i izbavit će nas; u njega se uzdamo, on će nas i dalje izbavljati."},{"v":11,"t":"A i vi ćete nam pomagati molitvom da bi mnogi za nas zahvaljivali Bogu na milosti koja nam je darovana posredovanjem mnogih."},{"v":12,"t":"A ovo je naša slava: svjedočansto naše savjesti da smo u svijetu živjeli - osobito prema vama - u svetosti i iskrenosti Božjoj, ne u mudrosti tjelesnoj, nego u Božjoj milosti."},{"v":13,"t":"Ta i ne pišemo vam drugo doli ovo što čitate i razumijete; a nadam se da ćete i do kraja razumjeti,"},{"v":14,"t":"kao što nas djelomično i razumjeste: da smo mi vaša slava kao i vi naša u Dan Gospodina našega Isusa."},{"v":15,"t":"U tom uvjerenju namjeravao sam najprije doći k vama"},{"v":16,"t":"i preko vas prijeći u Makedoniju pa se opet, da biste imali i drugu milost, iz Makedonije vratiti k vama da me vi otpratite u Judeju."},{"v":17,"t":"Pa jesam li možda bio lakomislen kad sam to namjeravao? Ili što namjeravam, po tijelu namjeravam te je u mene istodobno “Da, da!” i “Ne, ne!”?"},{"v":18,"t":"Bog je svjedok: naša riječ vama nije “Da!” i “Ne!”"},{"v":19,"t":"jer Sin Božji, Isus Krist, koga mi - ja i Silvan i Timotej - vama navijestismo nije bio “Da!” i “Ne!” nego u njemu bijaše “Da!”."},{"v":20,"t":"Doista, sva obećanja Božja u njemu su “Da!”. I stoga po njemu i naš “Amen!” Bogu na slavu!"},{"v":21,"t":"A Bog je onaj koji nas zajedno s vama utvrđuje za Krista; on nas i pomaza,"},{"v":22,"t":"on nas i zapečati i u srca naša dade zalog - Duha."},{"v":23,"t":"A ja prizivljem Boga za svjedoka: duše mi, da vas poštedim, nisam više dolazio u Korint."},{"v":24,"t":"Ta mi nismo gospodari vaše vjere, nego suradnici vaše radosti. Ta u vjeri ste postojani."}]},"2":{"fa":[{"v":1,"t":"اما در دل خود عزیمت داشتم که دیگر باحزن به نزد شما نیایم،"},{"v":2,"t":"زیرا اگر من شما رامحزون سازم، کیست که مرا شادی دهد جز او که از من محزون گشت؟"},{"v":3,"t":"و همین را نوشتم که مباداوقتی که بیایم محزون شوم از آنانی که می‌بایست سبب خوشی من بشوند، چونکه بر همه شمااعتماد می‌دارم که شادی من، شادی جمیع شمااست."},{"v":4,"t":"زیرا که از حزن و دلتنگی سخت و بااشکهای بسیار به شما نوشتم، نه تا محزون شویدبلکه تا بفهمید چه محبت بینهایتی با شما دارم."},{"v":5,"t":"و اگر کسی باعث غم شد، مرا محزون نساخت بلکه فی الجمله جمیع شما را تا بار زیاده ننهاده باشم."},{"v":6,"t":"کافی است آن کس را این سیاستی که از اکثر شما بدو رسیده است."},{"v":7,"t":"پس برعکس شما باید او را عفو نموده، تسلی دهید که مباداافزونی غم چنین شخص را فرو برد."},{"v":8,"t":"بنابراین، به شما التماس می‌دارم که با او محبت خود رااستوار نمایید."},{"v":9,"t":"زیرا که برای همین نیز نوشتم تادلیل شما را بدانم که در همه‌چیز مطیع می‌باشید."},{"v":10,"t":"اما هرکه را چیزی عفو نمایید، من نیز می‌کنم زیرا که آنچه من عفو کرده‌ام، هرگاه چیزی را عفوکرده باشم، به‌خاطر شما به حضور مسیح کرده‌ام،"},{"v":11,"t":"تا شیطان بر ما برتری نیابد، زیرا که از مکاید اوبی خبر نیستیم."},{"v":12,"t":"اما چون به تروآس بجهت بشارت مسیح آمدم و دروازه‌ای برای من در خداوند باز شد،"},{"v":13,"t":"در روح خود آرامی نداشتم، از آن رو که برادرخود تیطس را نیافتم، بلکه ایشان را وداع نموده، به مکادونیه آمدم."},{"v":14,"t":"لیکن شکر خدا راست که مارا در مسیح، دائم در موکب ظفر خود می‌برد وعطر معرفت خود را در هرجا بوسیله ما ظاهرمی کند."},{"v":15,"t":"زیرا خدا را عطر خوشبوی مسیح می‌باشیم هم در ناجیان و هم در هالکان."},{"v":16,"t":"امااینها را عطر موت، الی موت و آنها را عطر حیات الی حیات. و برای این امور کیست که کافی باشد؟"},{"v":17,"t":"زیرا مثل بسیاری نیستیم که کلام خدا را مغشوش سازیم، بلکه از ساده دلی و از جانب خدا در حضور خدا در مسیح سخن می‌گوییم."}],"en":[{"v":1,"t":"But I determined this for myself, that I would not come to you again in sorrow."},{"v":2,"t":"For if I make you grieve, then who will make me glad but he who is made to grieve by me?"},{"v":3,"t":"And I wrote this very thing to you, so that when I came, I wouldn’t have sorrow from them of whom I ought to rejoice; having confidence in you all that my joy would be shared by all of you."},{"v":4,"t":"For out of much affliction and anguish of heart I wrote to you with many tears, not that you should be made to grieve, but that you might know the love that I have so abundantly for you."},{"v":5,"t":"But if any has caused sorrow, he has caused sorrow not to me, but in part (that I not press too heavily) to you all."},{"v":6,"t":"This punishment which was inflicted by the many is sufficient for such a one;"},{"v":7,"t":"so that, on the contrary, you should rather forgive him and comfort him, lest by any means such a one should be swallowed up with his excessive sorrow."},{"v":8,"t":"Therefore I beg you to confirm your love toward him."},{"v":9,"t":"For to this end I also wrote, that I might know the proof of you, whether you are obedient in all things."},{"v":10,"t":"Now I also forgive whomever you forgive anything. For if indeed I have forgiven anything, I have forgiven that one for your sakes in the presence of Christ,"},{"v":11,"t":"that no advantage may be gained over us by Satan, for we are not ignorant of his schemes."},{"v":12,"t":"Now when I came to Troas for the Good News of Christ, and when a door was opened to me in the Lord,"},{"v":13,"t":"I had no relief for my spirit, because I didn’t find Titus my brother, but taking my leave of them, I went out into Macedonia."},{"v":14,"t":"Now thanks be to God who always leads us in triumph in Christ, and reveals through us the sweet aroma of his knowledge in every place."},{"v":15,"t":"For we are a sweet aroma of Christ to God in those who are saved and in those who perish:"},{"v":16,"t":"to the one a stench from death to death, to the other a sweet aroma from life to life. Who is sufficient for these things?"},{"v":17,"t":"For we are not as so many, peddling the word of God. But as of sincerity, but as of God, in the sight of God, we speak in Christ."}],"hr":[{"v":1,"t":"Odlučih dakle u sebi da neću k vama opet sa žalošću."},{"v":2,"t":"Jer ako ja vas ražalostim, a tko će mene obradovati ako ne onaj koga ja žalostim?"},{"v":3,"t":"Zato vam to i napisah da me, kada dođem, ne ražaloste oni koji bi mi imali biti na radost. Uzdam se doista u sve vas, da je moja radost - radost svih vas."},{"v":4,"t":"Pisah vam uistinu uz mnoge suze, iz velike nevolje i tjeskobe srca, ne da se ražalostite, nego da upoznate moju preveliku ljubav prema vama."},{"v":5,"t":"Ako me tko ražalostio, nije ražalostio mene, nego u neku ruku - da ne pretjeram - sve vas."},{"v":6,"t":"Dosta je takvu ona kazna od većine"},{"v":7,"t":"pa ga vi radije pomilujte i utješite da ga pretjerana žalost ne shrva."},{"v":8,"t":"Zato vas molim, iskažite mu ljubav."},{"v":9,"t":"Ta zato vam i pisah da vidim jeste li prokušani, jeste li u svemu poslušni."},{"v":10,"t":"Komu dakle vi što oprostite, tomu i ja; jer i ja, ako kome što oprostih, oprostih poradi vas - pred Kristom,"},{"v":11,"t":"da nas ne nadmudri Sotona. Ta znamo njegove namjere!"},{"v":12,"t":"Kada dođoh u Troadu poradi evanđelja Kristova, premda mi se otvoriše vrata u Gospodinu,"},{"v":13,"t":"ne bijaše mi duši spokoja što ne nađoh Tita, brata svoga; oprostih se stoga s njima i pođoh u Makedoniju."},{"v":14,"t":"Ali hvala Bogu koji nas u Kristu uvijek proslavlja te širi po nama na svakome mjestu miris svoga spoznanja."},{"v":15,"t":"Da, Kristov smo miomiris Bogu i među onima koji se spasavaju i među onima koji propadaju:"},{"v":16,"t":"ovima miris iz smrti za smrt, onima miris iz života za život. A tko je za to podoban?"},{"v":17,"t":"Uistinu, mi nismo kao mnogi koji trguju riječju Božjom, nego iskreno - kao od Boga pred Bogom - u Kristu govorimo."}]},"3":{"fa":[{"v":1,"t":"آیا باز به سفارش خود شروع می‌کنیم؟ وآیا مثل بعضی احتیاج به سفارش نامه جات به شما یا از شما داشته باشیم؟"},{"v":2,"t":"شما رساله ماهستید، نوشته شده در دلهای ما، معروف وخوانده شده جمیع آدمیان."},{"v":3,"t":"چونکه ظاهرشده‌اید که رساله مسیح می‌باشید، خدمت کرده شده از ما و نوشته شده نه به مرکب بلکه به روح خدای حی، نه بر الواح سنگ، بلکه بر الواح گوشتی دل."},{"v":4,"t":"اما بوسیله مسیح چنین اعتماد به خدا داریم."},{"v":5,"t":"نه آنکه کافی باشیم که چیزی را به خود تفکر کنیم که گویا از ما باشد، بلکه کفایت مااز خداست."},{"v":6,"t":"که او ما را هم کفایت داد تا عهدجدید را خادم شویم، نه حرف را بلکه روح رازیرا که حرف می‌کشد لیکن روح زنده می‌کند."},{"v":7,"t":"اما اگر خدمت موت که در حرف بود و برسنگها تراشیده شده با جلال می‌بود، بحدی که بنی‌اسرائیل نمی توانستند صورت موسی را نظاره کنند به‌سبب جلال چهره او که فانی بود،"},{"v":8,"t":"چگونه خدمت روح بیشتر با جلال نخواهد بود؟"},{"v":9,"t":"زیراهرگاه خدمت قصاص با جلال باشد، چند مرتبه زیادتر خدمت عدالت در جلال خواهد افزود."},{"v":10,"t":"زیرا که آنچه جلال داده شده بود نیز بدین نسبت جلالی نداشت به‌سبب این جلال فایق."},{"v":11,"t":"زیرا اگر آن فانی با جلال بودی، هرآینه این باقی از طریق اولی در جلال خواهد بود."},{"v":12,"t":"پس چون چنین امید داریم، با کمال دلیری سخن می‌گوییم."},{"v":13,"t":"و نه مانند موسی که نقابی برچهره خود کشید تا بنی‌اسرائیل، تمام شدن این فانی را نظر نکنند،"},{"v":14,"t":"بلکه ذهن ایشان غلیظ شدزیرا که تا امروز همان نقاب در خواندن عهد عتیق باقی است و کشف نشده است، زیرا که فقط درمسیح باطل می‌گردد."},{"v":15,"t":"بلکه تا امروز وقتی که موسی را می‌خوانند، نقاب بر دل ایشان برقرارمی ماند."},{"v":16,"t":"لیکن هرگاه به سوی خداوند رجوع کند، نقاب برداشته می‌شود."},{"v":17,"t":"اما خداوند روح است و جایی که روح خداوند است، آنجا آزادی است."},{"v":18,"t":"لیکن همه ما چون با چهره بی‌نقاب جلال خداوند را در آینه می‌نگریم، از جلال تاجلال به همان صورت متبدل می‌شویم، چنانکه از خداوند که روح است."}],"en":[{"v":1,"t":"Are we beginning again to commend ourselves? Or do we need, as do some, letters of commendation to you or from you?"},{"v":2,"t":"You are our letter, written in our hearts, known and read by all men,"},{"v":3,"t":"being revealed that you are a letter of Christ, served by us, written not with ink, but with the Spirit of the living God; not in tablets of stone, but in tablets that are hearts of flesh."},{"v":4,"t":"Such confidence we have through Christ toward God,"},{"v":5,"t":"not that we are sufficient of ourselves to account anything as from ourselves; but our sufficiency is from God,"},{"v":6,"t":"who also made us sufficient as servants of a new covenant, not of the letter but of the Spirit. For the letter kills, but the Spirit gives life."},{"v":7,"t":"But if the service of death, written engraved on stones, came with glory, so that the children of Israel could not look steadfastly on the face of Moses for the glory of his face, which was passing away,"},{"v":8,"t":"won’t service of the Spirit be with much more glory?"},{"v":9,"t":"For if the service of condemnation has glory, the service of righteousness exceeds much more in glory."},{"v":10,"t":"For most certainly that which has been made glorious has not been made glorious in this respect, by reason of the glory that surpasses."},{"v":11,"t":"For if that which passes away was with glory, much more that which remains is in glory."},{"v":12,"t":"Having therefore such a hope, we use great boldness of speech,"},{"v":13,"t":"and not as Moses, who put a veil on his face so that the children of Israel wouldn’t look steadfastly on the end of that which was passing away."},{"v":14,"t":"But their minds were hardened, for until this very day at the reading of the old covenant the same veil remains, because in Christ it passes away."},{"v":15,"t":"But to this day, when Moses is read, a veil lies on their heart."},{"v":16,"t":"But whenever someone turns to the Lord, the veil is taken away."},{"v":17,"t":"Now the Lord is the Spirit; and where the Spirit of the Lord is, there is liberty."},{"v":18,"t":"But we all, with unveiled face seeing the glory of the Lord as in a mirror, are transformed into the same image from glory to glory, even as from the Lord, the Spirit."}],"hr":[{"v":1,"t":"Počinjemo li opet sami sebe preporučivati? Ili trebamo li, kao neki, preporučna pisma na vas ili od vas?"},{"v":2,"t":"Vi ste pismo naše, upisano u srcima vašim; znaju ga i čitaju svi ljudi."},{"v":3,"t":"Vi ste, očito, pismo Kristovo kojemu mi poslužismo, napisano ne crnilom, nego Duhom Boga živoga; ne na pločama kamenim, nego na pločama od mesa, u srcima."},{"v":4,"t":"Takvo pouzdanje imamo po Kristu u Boga."},{"v":5,"t":"Ne kao da smo sami sobom, kao od sebe, sposobni što pomisliti, nego naša je sposobnost od Boga."},{"v":6,"t":"On nas osposobi za poslužitelje novoga Saveza, ne slova, nego Duha; jer slovo ubija, a Duh oživljuje."},{"v":7,"t":"Pa ako je smrtonosna služba, slovima uklesana u kamenju, bila tako slavna da sinovi Izraelovi nisu mogli pogledati u lice Mojsijevo zbog prolazne slave lica njegova,"},{"v":8,"t":"koliko li će slavnija biti služba Duha."},{"v":9,"t":"Jer ako je služba osude bila slavna, mnogo je slavnija služba pravednosti."},{"v":10,"t":"I zbilja, nije ni bilo proslavljeno ono što je u toj mjeri proslavljeno, ako se usporedi s uzvišenijom slavom."},{"v":11,"t":"Jer ako je ono prolazno bilo slavno, mnogo je slavnije ovo što ostaje."},{"v":12,"t":"Imajući dakle takvo pouzdanje, nastupamo sa svom otvorenošću,"},{"v":13,"t":"a ne kao Mojsije koji je stavljao prijevjes na lice da sinovi Izraelovi ne vide svršetak prolaznoga."},{"v":14,"t":"Ali otvrdnu im pamet. Doista, do dana današnjega zastire taj prijevjes čitanje Staroga zavjeta: nije im otkriveno da je u Kristu prestao."},{"v":15,"t":"Naprotiv, kad god se čita Mojsije, do danas prijevjes zastire srce njihovo."},{"v":16,"t":"Ali kad se Izrael obrati Gospodinu, skinut će se prijevjes."},{"v":17,"t":"Gospodin je Duh, a gdje je Duh Gospodnji, ondje je sloboda."},{"v":18,"t":"A svi mi, koji otkrivenim licem odrazujemo slavu Gospodnju, po Duhu se Gospodnjem preobražavamo u istu sliku - iz slave u slavu."}]},"4":{"fa":[{"v":1,"t":"بنابراین چون این خدمت را داریم، چنانکه رحمت یافته‌ایم، خسته خاطر نمی شویم."},{"v":2,"t":"بلکه خفایای رسوایی را ترک کرده، به مکر رفتارنمی کنیم و کلام خدا را مغشوش نمی سازیم، بلکه به اظهار راستی، خود را به ضمیر هرکس درحضور خدا مقبول می‌سازیم."},{"v":3,"t":"لیکن اگر بشارت ما مخفی است، بر هالکان مخفی است،"},{"v":4,"t":"که درایشان خدای این جهان فهم های بی‌ایمانشان راکور گردانیده است که مبادا تجلی بشارت جلال مسیح که صورت خداست، ایشان را روشن سازد."},{"v":5,"t":"زیرا به خویشتن موعظه نمی کنیم بلکه به مسیح عیسی خداوند، اما به خویشتن که غلام شما هستیم بخاطر عیسی."},{"v":6,"t":"زیرا خدایی که گفت تانور از ظلمت درخشید، همان است که در دلهای ما درخشید تا نور معرفت جلال خدا در چهره عیسی مسیح از ما بدرخشد."},{"v":7,"t":"لیکن این خزینه را در ظروف خاکی داریم تابرتری قوت از آن خدا باشد نه از جانب ما."},{"v":8,"t":"درهرچیز زحمت کشیده، ولی در شکنجه نیستیم؛ متحیر ولی مایوس نی؛"},{"v":9,"t":"تعاقب کرده شده، لیکن نه متروک؛ افکنده شده، ولی هلاک شده نی؛"},{"v":10,"t":"پیوسته قتل عیسی خداوند را در جسد خودحمل می‌کنیم تا حیات عیسی هم در بدن ما ظاهرشود."},{"v":11,"t":"زیرا ما که زنده‌ایم، دائم بخاطر عیسی به موت سپرده می‌شویم تا حیات عیسی نیز درجسد فانی ما پدید آید."},{"v":12,"t":"پس موت در ما کارمی کند ولی حیات در شما."},{"v":13,"t":"اما چون همان روح ایمان را داریم، بحسب آنچه مکتوب است «ایمان آوردم پس سخن گفتم»، ما نیز چون ایمان داریم، از اینرو سخن می‌گوییم."},{"v":14,"t":"چون می‌دانیم او که عیسی خداوندرا برخیزانید، ما را نیز با عیسی خواهد برخیزانیدو با شما حاضر خواهد ساخت."},{"v":15,"t":"زیرا که همه‌چیز برای شما است تا آن فیضی که بوسیله بسیاری افزوده شده است، شکرگزاری را برای تمجید خدا بیفزاید."},{"v":16,"t":"از این جهت خسته خاطرنمی شویم، بلکه هرچند انسانیت ظاهری ما فانی می‌شود، لیکن باطن روز بروز تازه می‌گردد."},{"v":17,"t":"زیرا که این زحمت سبک ما که برای لحظه‌ای است، بار جاودانی جلال را برای ما زیاده و زیاده پیدا می‌کند."},{"v":18,"t":"در حالی که ما نظر نمی کنیم به چیزهای دیدنی، بلکه به چیزهای نادیدنی، زیرا که آنچه دیدنی است، زمانی است و نادیدنی جاودانی."}],"en":[{"v":1,"t":"Therefore, seeing we have this ministry, even as we obtained mercy, we don’t faint."},{"v":2,"t":"But we have renounced the hidden things of shame, not walking in craftiness nor handling the word of God deceitfully, but by the manifestation of the truth commending ourselves to every man’s conscience in the sight of God."},{"v":3,"t":"Even if our Good News is veiled, it is veiled in those who are dying,"},{"v":4,"t":"in whom the god of this world has blinded the minds of the unbelieving, that the light of the Good News of the glory of Christ, who is the image of God, should not dawn on them."},{"v":5,"t":"For we don’t preach ourselves, but Christ Jesus as Lord, and ourselves as your servants for Jesus’ sake,"},{"v":6,"t":"seeing it is God who said, “Light will shine out of darkness,” who has shone in our hearts to give the light of the knowledge of the glory of God in the face of Jesus Christ."},{"v":7,"t":"But we have this treasure in clay vessels, that the exceeding greatness of the power may be of God and not from ourselves."},{"v":8,"t":"We are pressed on every side, yet not crushed; perplexed, yet not to despair;"},{"v":9,"t":"pursued, yet not forsaken; struck down, yet not destroyed;"},{"v":10,"t":"always carrying in the body the putting to death of the Lord Jesus, that the life of Jesus may also be revealed in our body."},{"v":11,"t":"For we who live are always delivered to death for Jesus’ sake, that the life also of Jesus may be revealed in our mortal flesh."},{"v":12,"t":"So then death works in us, but life in you."},{"v":13,"t":"But having the same spirit of faith, according to that which is written, “I believed, and therefore I spoke.” We also believe, and therefore we also speak,"},{"v":14,"t":"knowing that he who raised the Lord Jesus will raise us also with Jesus, and will present us with you."},{"v":15,"t":"For all things are for your sakes, that the grace, being multiplied through the many, may cause the thanksgiving to abound to the glory of God."},{"v":16,"t":"Therefore we don’t faint, but though our outward person is decaying, yet our inward person is renewed day by day."},{"v":17,"t":"For our light affliction, which is for the moment, works for us more and more exceedingly an eternal weight of glory,"},{"v":18,"t":"while we don’t look at the things which are seen, but at the things which are not seen. For the things which are seen are temporal, but the things which are not seen are eternal."}],"hr":[{"v":1,"t":"Zato, budući da po milosrđu imamo ovu službu, ne malakšemo."},{"v":2,"t":"Ali odrekosmo se sramotnoga prikrivanja: ne nastupamo lukavo niti izopačujemo riječ Božju, nego se objavljivanjem istine preporučujemo svakoj savjesti ljudskoj pred Bogom."},{"v":3,"t":"Ako je i zastrto evanđelje naše, u onima je zastrto koji propadaju:"},{"v":4,"t":"u onima kojima bog ovoga svijeta oslijepi pameti nevjerničke da ne zasvijetli svjetlost evanđelja slave Krista koji je slika Božja."},{"v":5,"t":"Jer ne propovijedamo same sebe, nego Krista Isusa Gospodinom, a sebe slugama vašim poradi Isusa."},{"v":6,"t":"Ta Bog koji reče: Neka iz tame svjetlost zasine!, on zasvijetli u srcima našim da nam spoznanje slave Božje zasvijetli na licu Kristovu."},{"v":7,"t":"To pak blago imamo u glinenim posudama da izvanredna ona snaga bude očito Božja, a ne od nas."},{"v":8,"t":"U svemu pritisnuti, ali ne pritiješnjeni; dvoumeći, ali ne zdvajajući;"},{"v":9,"t":"progonjeni, ali ne napušteni; obarani, ali ne oboreni -"},{"v":10,"t":"uvijek umiranje Isusovo u tijelu pronosimo da se i život Isusov u tijelu našem očituje."},{"v":11,"t":"Doista, mi se živi uvijek na smrt predajemo poradi Isusa da se i život Isusov očituje u našem smrtnom tijelu."},{"v":12,"t":"Tako smrt djeluje u nama, život u vama."},{"v":13,"t":"A budući da imamo isti duh vjere kao što je pisano: Uzvjerovah, zato besjedim, i mi vjerujemo pa zato i besjedimo."},{"v":14,"t":"Ta znamo: onaj koji je uskrisio Gospodina Isusa i nas će s Isusom uskrisiti i zajedno s vama uza se postaviti."},{"v":15,"t":"A sve je to za vas: da milost - umnožena - zahvaljivanjem mnogih izobiluje Bogu na slavu."},{"v":16,"t":"Zato ne malakšemo. Naprotiv, ako se naš izvanji čovjek i raspada, nutarnji se iz dana u dan obnavlja."},{"v":17,"t":"Ta ova malenkost naše časovite nevolje donosi nam obilato, sve obilatije, breme vječne slave"},{"v":18,"t":"jer nama nije do vidljivog nego do nevidljivog: ta vidljivo je privremeno, a nevidljivo - vječno."}]},"5":{"fa":[{"v":1,"t":"زیرا می‌دانیم که هرگاه این خانه زمینی خیمه ما ریخته شود، عمارتی از خداداریم، خانه‌ای ناساخته شده به‌دستها و جاودانی در آسمانها."},{"v":2,"t":"زیرا که در این هم آه می‌کشیم، چونکه مشتاق هستیم که خانه خود را که ازآسمان است بپوشیم،"},{"v":3,"t":"اگر فی الواقع پوشیده و نه عریان یافت شویم."},{"v":4,"t":"از آنرو که ما نیز که در این خیمه هستیم، گرانبار شده، آه می‌کشیم، از آن جهت که نمی خواهیم این را بیرون کنیم، بلکه آن را بپوشیم تا فانی در حیات غرق شود."},{"v":5,"t":"اما او که ما را برای این درست ساخت خدا است که بیعانه روح را به ما می‌دهد."},{"v":6,"t":"پس دائم خاطرجمع هستیم و می‌دانیم که مادامی که در بدن متوطنیم، از خداوند غریب می‌باشیم."},{"v":7,"t":"(زیرا که به ایمان رفتار می‌کنیم نه به دیدار)"},{"v":8,"t":"پس خاطرجمع هستیم و این را بیشترمی پسندیم که از بدن غربت کنیم و به نزد خداوندمتوطن شویم."},{"v":9,"t":"لهذا حریص هستیم بر اینکه خواه متوطن و خواه غریب، پسندیده او باشیم."},{"v":10,"t":"زیرا لازم است که همه ما پیش مسند مسیح حاضر شویم تا هرکس اعمال بدنی خود را بیابد، بحسب آنچه کرده باشد، چه نیک چه بد."},{"v":11,"t":"پس چون ترس خدا را دانسته‌ایم، مردم رادعوت می‌کنیم. اما به خدا ظاهر شده‌ایم و امیدوارم به ضمایر شما هم ظاهر خواهیم شد."},{"v":12,"t":"زیرا بار دیگر برای خود به شما سفارش نمی کنیم، بلکه سبب افتخار درباره خود به شمامی دهیم تا شما را جوابی باشد برای آنانی که درظاهر نه در دل فخر می‌کنند."},{"v":13,"t":"زیرا اگر بی‌خودهستیم برای خداست و اگر هشیاریم برای شمااست."},{"v":14,"t":"زیرا محبت مسیح ما را فرو گرفته است، چونکه این را دریافتیم که یک نفر برای همه مردپس همه مردند."},{"v":15,"t":"و برای همه مرد تا آنانی که زنده‌اند، از این به بعد برای خویشتن زیست نکنندبلکه برای او که برای ایشان مرد و برخاست."},{"v":16,"t":"بنابراین، ما بعد از این هیچ‌کس را بحسب جسم نمی شناسیم، بلکه هرگاه مسیح را هم بحسب جسم شناخته بودیم، الان دیگر او رانمی شناسیم."},{"v":17,"t":"پس اگر کسی در مسیح باشد، خلقت تازه‌ای است؛ چیزهای کهنه درگذشت، اینک همه‌چیز تازه شده است."},{"v":18,"t":"و همه‌چیز ازخدا که ما را بواسطه عیسی مسیح با خود مصالحه داده و خدمت مصالحه را به ما سپرده است."},{"v":19,"t":"یعنی‌اینکه خدا در مسیح بود و جهان را باخود مصالحه می‌داد و خطایای ایشان را بدیشان محسوب نداشت و کلام مصالحه را به ما سپرد."},{"v":20,"t":"پس برای مسیح ایلچی هستیم که گویا خدا به زبان ما وعظ می‌کند. پس بخاطر مسیح استدعامی کنیم که با خدا مصالحه کنید."},{"v":21,"t":"زیرا او را که گناه نشناخت در راه ما گناه ساخت تا ما در وی عدالت خدا شویم."}],"en":[{"v":1,"t":"For we know that if the earthly house of our tent is dissolved, we have a building from God, a house not made with hands, eternal, in the heavens."},{"v":2,"t":"For most certainly in this we groan, longing to be clothed with our habitation which is from heaven,"},{"v":3,"t":"if indeed being clothed, we will not be found naked."},{"v":4,"t":"For indeed we who are in this tent do groan, being burdened, not that we desire to be unclothed, but that we desire to be clothed, that what is mortal may be swallowed up by life."},{"v":5,"t":"Now he who made us for this very thing is God, who also gave to us the down payment of the Spirit."},{"v":6,"t":"Therefore we are always confident and know that while we are at home in the body, we are absent from the Lord;"},{"v":7,"t":"for we walk by faith, not by sight."},{"v":8,"t":"We are courageous, I say, and are willing rather to be absent from the body and to be at home with the Lord."},{"v":9,"t":"Therefore also we make it our aim, whether at home or absent, to be well pleasing to him."},{"v":10,"t":"For we must all be revealed before the judgment seat of Christ that each one may receive the things in the body according to what he has done, whether good or bad."},{"v":11,"t":"Knowing therefore the fear of the Lord, we persuade men, but we are revealed to God, and I hope that we are revealed also in your consciences."},{"v":12,"t":"For we are not commending ourselves to you again, but speak as giving you occasion of boasting on our behalf, that you may have something to answer those who boast in appearance and not in heart."},{"v":13,"t":"For if we are beside ourselves, it is for God. Or if we are of sober mind, it is for you."},{"v":14,"t":"For the love of Christ compels us; because we judge thus: that one died for all, therefore all died."},{"v":15,"t":"He died for all, that those who live should no longer live to themselves, but to him who for their sakes died and rose again."},{"v":16,"t":"Therefore we know no one according to the flesh from now on. Even though we have known Christ according to the flesh, yet now we know him so no more."},{"v":17,"t":"Therefore if anyone is in Christ, he is a new creation. The old things have passed away. Behold, all things have become new."},{"v":18,"t":"But all things are of God, who reconciled us to himself through Jesus Christ, and gave to us the ministry of reconciliation;"},{"v":19,"t":"namely, that God was in Christ reconciling the world to himself, not reckoning to them their trespasses, and having committed to us the word of reconciliation."},{"v":20,"t":"We are therefore ambassadors on behalf of Christ, as though God were entreating by us: we beg you on behalf of Christ, be reconciled to God."},{"v":21,"t":"For him who knew no sin he made to be sin on our behalf, so that in him we might become the righteousness of God."}],"hr":[{"v":1,"t":"Znamo doista: ako se razruši naš zemaljski dom, šator, imamo zdanje od Boga, dom nerukotvoren, vječan na nebesima."},{"v":2,"t":"U ovome doista stenjemo i čeznemo da se povrh njega zaodjenemo svojim nebeskim obitavalištem;"},{"v":3,"t":"dakako, ako se nađemo obučeni, ne goli."},{"v":4,"t":"Da, i mi koji smo u ovom šatoru, stenjemo opterećeni jer nećemo da budemo svučeni, nego da se još obučemo da život iskapi što je smrtno."},{"v":5,"t":"A zato nas je sazdao Bog - on koji nam dade zalog Duha."},{"v":6,"t":"Uvijek smo stoga puni pouzdanja makar i znamo: naseljeni u tijelu, iseljeni smo od Gospodina."},{"v":7,"t":"Ta u vjeri hodimo, ne u gledanju."},{"v":8,"t":"Da, puni smo pouzdanja i najradije bismo se iselili iz tijela i naselili kod Gospodina."},{"v":9,"t":"Zato se i trsimo da mu omilimo, bilo naseljeni, bilo iseljeni."},{"v":10,"t":"Jer svima nam se pojaviti pred sudištem Kristovim da svaki dobije što je kroz tijelo zaradio, bilo dobro, bilo zlo."},{"v":11,"t":"Prožeti dakle strahom Gospodnjim uvjeravamo ljude; razotkriveni smo Bogu, a nadam se - i vašim savjestima."},{"v":12,"t":"Ne preporučujemo vam opet sami sebe, nego vam dajemo prigodu ponositi se nama, da imate odgovor za one koji se diče licem, a ne srcem."},{"v":13,"t":"Doista, ako bijasmo “izvan sebe” - Bogu bijasmo; ako li “pri sebi” - vama bijasmo."},{"v":14,"t":"Jer ljubav nas Kristova obuzima kad promatramo ovo: jedan za sve umrije, svi dakle umriješe;"},{"v":15,"t":"i za sve umrije da oni koji žive ne žive više sebi, nego onomu koji za njih umrije i uskrsnu."},{"v":16,"t":"Stoga mi od sada nikoga ne poznajemo po tijelu; ako smo i poznavali po tijelu Krista, sada ga tako više ne poznajemo."},{"v":17,"t":"Dakle, je li tko u Kristu, nov je stvor. Staro uminu, novo, gle, nasta!"},{"v":18,"t":"A sve je od Boga koji nas sa sobom pomiri po Kristu i povjeri nam službu pomirenja."},{"v":19,"t":"Jer Bog je u Kristu svijet sa sobom pomirio ne ubrajajući im opačina njihovih i polažući u nas riječ pomirenja."},{"v":20,"t":"Kristovi smo dakle poslanici; Bog vas po nama nagovara. Umjesto Krista zaklinjemo: dajte, pomirite se s Bogom!"},{"v":21,"t":"Njega koji ne okusi grijeha Bog za nas grijehom učini da mi budemo pravednost Božja u njemu."}]},"6":{"fa":[{"v":1,"t":"پس چون همکاران او هستیم، التماس می نماییم که فیض خدا را بی‌فایده نیافته باشید."},{"v":2,"t":"زیرا می‌گوید: «در وقت مقبول تو را مستجاب فرمودم و در روز نجات تو را اعانت کردم.» اینک الحال زمان مقبول است؛ اینک الان روز نجات است."},{"v":3,"t":"در هیچ‌چیز لغزش نمی دهیم که مباداخدمت ما ملامت کرده شود،"},{"v":4,"t":"بلکه در هر امری خود را ثابت می‌کنیم که خدام خدا هستیم: درصبر بسیار، در زحمات، در حاجات در تنگیها،"},{"v":5,"t":"در تازیانه‌ها، در زندانها، در فتنه‌ها، در محنتها، در بی‌خوابیها، در گرسنگیها،"},{"v":6,"t":"در طهارت، درمعرفت، در حلم، در مهربانی، در روح‌القدس، درمحبت بی‌ریا،"},{"v":7,"t":"در کلام حق، در قوت خدا بااسلحه عدالت بر طرف راست و چپ،"},{"v":8,"t":"به عزت وذلت و بدنامی و نیکنامی. چون گمراه کنندگان واینک راستگو هستیم؛"},{"v":9,"t":"چون مجهول و اینک معروف؛ چون در حالت موت و اینک زنده هستیم؛ چون سیاست کرده شده، اما مقتول نی؛"},{"v":10,"t":"چون محزون، ولی دائم شادمان؛ چون فقیر واینک بسیاری را دولتمند می‌سازیم؛ چون بی‌چیز، اما مالک همه‌چیز."},{"v":11,"t":"‌ای قرنتیان، دهان ما به سوی شما گشاده ودل ما وسیع شده است."},{"v":12,"t":"در ما تنگ نیستید لیکن در احشای خود تنگ هستید."},{"v":13,"t":"پس در جزای این، زیرا که به فرزندان خود سخن می‌گویم، شمانیز گشاده شوید."},{"v":14,"t":"زیر یوغ ناموافق با بی‌ایمانان مشوید، زیرا عدالت را با گناه چه رفاقت و نور را باظلمت چه شراکت است؟"},{"v":15,"t":"و مسیح را با بلیعال چه مناسبت و مومن را با کافر چه نصیب است؟"},{"v":16,"t":"و هیکل خدا را با بتها چه موافقت؟ زیرا شماهیکل خدای حی می‌باشید، چنانکه خدا گفت که «در ایشان ساکن خواهم بود و در ایشان راه خواهم رفت و خدای ایشان خواهم بود، و ایشان قوم من خواهند بود.»"},{"v":17,"t":"پس خداوند می‌گوید: «از میان ایشان بیرون آیید و جدا شوید و چیزناپاک را لمس مکنید تا من شما را مقبول بدارم،"},{"v":18,"t":"و شما را پدر خواهم بود و شما مرا پسران ودختران خواهید بود؛ خداوند قادر مطلق می‌گوید.»"}],"en":[{"v":1,"t":"Working together, we entreat also that you do not receive the grace of God in vain."},{"v":2,"t":"For he says, “At an acceptable time I listened to you. In a day of salvation I helped you.” Behold, now is the acceptable time. Behold, now is the day of salvation."},{"v":3,"t":"We give no occasion of stumbling in anything, that our service may not be blamed,"},{"v":4,"t":"but in everything commending ourselves as servants of God: in great endurance, in afflictions, in hardships, in distresses,"},{"v":5,"t":"in beatings, in imprisonments, in riots, in labors, in watchings, in fastings,"},{"v":6,"t":"in pureness, in knowledge, in perseverance, in kindness, in the Holy Spirit, in sincere love,"},{"v":7,"t":"in the word of truth, in the power of God, by the armor of righteousness on the right hand and on the left,"},{"v":8,"t":"by glory and dishonor, by evil report and good report, as deceivers and yet true,"},{"v":9,"t":"as unknown and yet well known, as dying and behold—we live, as punished and not killed,"},{"v":10,"t":"as sorrowful yet always rejoicing, as poor yet making many rich, as having nothing and yet possessing all things."},{"v":11,"t":"Our mouth is open to you, Corinthians. Our heart is enlarged."},{"v":12,"t":"You are not restricted by us, but you are restricted by your own affections."},{"v":13,"t":"Now in return—I speak as to my children—you also open your hearts."},{"v":14,"t":"Don’t be unequally yoked with unbelievers, for what fellowship do righteousness and iniquity have? Or what fellowship does light have with darkness?"},{"v":15,"t":"What agreement does Christ have with Belial? Or what portion does a believer have with an unbeliever?"},{"v":16,"t":"What agreement does a temple of God have with idols? For you are a temple of the living God. Even as God said, “I will dwell in them and walk in them. I will be their God and they will be my people.”"},{"v":17,"t":"Therefore “‘Come out from among them, and be separate,’ says the Lord. ‘Touch no unclean thing. I will receive you."},{"v":18,"t":"I will be to you a Father. You will be to me sons and daughters,’ says the Lord Almighty.”"}],"hr":[{"v":1,"t":"Kao suradnici opominjemo vas da ne primite uzalud milosti Božje."},{"v":2,"t":"Jer on veli: U vrijeme milosti usliših te i u dan spasa pomogoh ti. Evo sad je vrijeme milosno, evo sad je vrijeme spasa."},{"v":3,"t":"Ni u čemu ne dajemo nikakve sablazni da se ne kudi ova služba,"},{"v":4,"t":"nego se u svemu iskazujemo kao poslužitelji Božji: velikom postojanošću u nevoljama, u potrebama, u tjeskobama,"},{"v":5,"t":"pod udarcima, u tamnicama, u bunama, u naporima, u bdjenjima, u postovima,"},{"v":6,"t":"u čistoći, u spoznanju, u velikodušnosti, u dobroti, u Duhu Svetomu, u ljubavi nehinjenoj,"},{"v":7,"t":"u riječi istinitoj, u snazi Božjoj; oružjem pravde zdesna i slijeva;"},{"v":8,"t":"slavom i sramotom; zlim i dobrim glasom; kao zavodnici, a istiniti;"},{"v":9,"t":"kao nepoznati, a poznati; kao umirući, a evo živimo; kao kažnjeni, a ne ubijeni;"},{"v":10,"t":"kao žalosni, a uvijek radosni; kao siromašni, a mnoge obogaćujemo; kao oni koji ništa nemaju, a sve posjeduju."},{"v":11,"t":"Usta su naša otvorena vama, Korinćani, srce naše rašireno."},{"v":12,"t":"Nije vam tijesno u nama, ali je tijesno u vašim grudima."},{"v":13,"t":"Za uzdarje - kao djeci govorim - raširite se i vi."},{"v":14,"t":"Ne ujarmljujte se s nevjernicima. Ta što ima pravednost s bezakonjem? Ili kakvo zajedništvo svjetlo s tamom?"},{"v":15,"t":"Kakvu slogu Krist s Belijarom? Ili kakav dio vjernik s nevjernikom?"},{"v":16,"t":"Kakav sporazum hram Božji s idolima? Jer mi smo hram Boga živoga, kao što reče Bog: Prebivat ću u njima i hoditi među njima; i bit ću Bog njihov, a oni narod moj."},{"v":17,"t":"Zato iziđite iz njihove sredine i odvojite se, govori Gospodin, i ništa nečisto ne dotičite i ja ću vas primiti."},{"v":18,"t":"I bit ću vam otac i vi ćete mi biti sinovi i kćeri, veli Gospodin Svemogući."}]},"7":{"fa":[{"v":1,"t":"پس‌ای عزیزان، چون این وعده‌ها راداریم، خویشتن را از هر نجاست جسم وروح طاهر بسازیم و قدوسیت را در خدا ترسی به‌کمال رسانیم."},{"v":2,"t":"ما را در دلهای خود جا دهید. بر هیچ‌کس ظلم نکردیم و هیچ‌کس را فاسد نساختیم وهیچ‌کس را مغبون ننمودیم."},{"v":3,"t":"این را از روی مذمت نمی گویم، زیرا پیش گفتم که در دل ماهستید تا در موت و حیات با هم باشیم."},{"v":4,"t":"مرا برشما اعتماد کلی و درباره شما فخر کامل است. ازتسلی سیر گشته‌ام و در هر زحمتی که بر مامی آید، شادی وافر می‌کنم."},{"v":5,"t":"زیرا چون به مکادونیه هم رسیدیم، جسم ماآرامی نیافت، بلکه در هرچیز زحمت کشیدیم؛ در ظاهر، نزاعها و در باطن، ترسها بود."},{"v":6,"t":"لیکن خدایی که تسلی دهنده افتادگان است، ما را به آمدن تیطس تسلی بخشید."},{"v":7,"t":"و نه از آمدن او تنهابلکه به آن تسلی نیز که او در شما یافته بود، چون ما را مطلع ساخت از شوق شما و نوحه گری شماو غیرتی که درباره من داشتید، به نوعی که بیشترشادمان گردیدم."},{"v":8,"t":"زیرا که هرچند شما را به آن رساله محزون ساختم، پشیمان نیستم، اگرچه پشیمان هم بودم زیرا یافتم که آن رساله شما رااگر هم به ساعتی، غمگین ساخت."},{"v":9,"t":"الحال شادمانم، نه از آنکه غم خوردید بلکه از اینکه غم شما به توبه انجامید، زیرا که غم شما برای خدابود تا به هیچ وجه زیانی از ما به شما نرسد."},{"v":10,"t":"زیرا غمی که برای خداست منشا توبه می‌باشد به جهت نجات که از آن پشیمانی نیست؛ اما غم دنیوی منشا موت است."},{"v":11,"t":"زیرا اینک همین‌که غم شما برای خدا بود، چگونه کوشش، بل احتجاج، بل خشم، بل ترس، بل اشتیاق، بل غیرت، بل انتقام را در شما پدید آورد. در هر چیزخود را ثابت کردید که در این امر مبرا هستید."},{"v":12,"t":"باری هرگاه به شما نوشتم، بجهت آن ظالم یا مظلوم نبود، بلکه تا غیرت ما درباره شما به شمادر حضور خدا ظاهر شود."},{"v":13,"t":"و از این جهت تسلی یافتیم لیکن در تسلی خود شادی ما ازخوشی تیطس بینهایت زیاده گردید چونکه روح او از جمیع شما آرامی یافته بود."},{"v":14,"t":"زیرا اگردرباره شما بدو فخر کردم، خجل نشدم بلکه چنانکه همه سخنان را به شما به راستی گفتیم، همچنین فخر ما به تیطس راست شد."},{"v":15,"t":"و خاطراو به سوی شما زیادتر مایل گردید، چونکه اطاعت جمیع شما را به یاد می‌آورد که چگونه به ترس و لرز او را پذیرفتید."},{"v":16,"t":"شادمانم که درهرچیز بر شما اعتماد دارم."}],"en":[{"v":1,"t":"Having therefore these promises, beloved, let’s cleanse ourselves from all defilement of flesh and spirit, perfecting holiness in the fear of God."},{"v":2,"t":"Open your hearts to us. We wronged no one. We corrupted no one. We took advantage of no one."},{"v":3,"t":"I say this not to condemn you, for I have said before that you are in our hearts to die together and live together."},{"v":4,"t":"Great is my boldness of speech toward you. Great is my boasting on your behalf. I am filled with comfort. I overflow with joy in all our affliction."},{"v":5,"t":"For even when we had come into Macedonia, our flesh had no relief, but we were afflicted on every side. Fightings were outside. Fear was inside."},{"v":6,"t":"Nevertheless, he who comforts the lowly, God, comforted us by the coming of Titus,"},{"v":7,"t":"and not by his coming only, but also by the comfort with which he was comforted in you while he told us of your longing, your mourning, and your zeal for me, so that I rejoiced still more."},{"v":8,"t":"For though I grieved you with my letter, I do not regret it, though I did regret it. For I see that my letter made you grieve, though just for a while."},{"v":9,"t":"I now rejoice, not that you were grieved, but that you were grieved to repentance. For you were grieved in a godly way, that you might suffer loss by us in nothing."},{"v":10,"t":"For godly sorrow produces repentance leading to salvation, which brings no regret. But the sorrow of the world produces death."},{"v":11,"t":"For behold, this same thing, that you were grieved in a godly way, what earnest care it worked in you. Yes, what defense, indignation, fear, longing, zeal, and vindication! In everything you demonstrated yourselves to be pure in the matter."},{"v":12,"t":"So although I wrote to you, I wrote not for his cause that did the wrong, nor for his cause that suffered the wrong, but that your earnest care for us might be revealed in you in the sight of God."},{"v":13,"t":"Therefore we have been comforted. In our comfort we rejoiced the more exceedingly for the joy of Titus, because his spirit has been refreshed by you all."},{"v":14,"t":"For if in anything I have boasted to him on your behalf, I was not disappointed. But as we spoke all things to you in truth, so our glorying also which I made before Titus was found to be truth."},{"v":15,"t":"His affection is more abundantly toward you, while he remembers all of your obedience, how with fear and trembling you received him."},{"v":16,"t":"I rejoice that in everything I am confident concerning you."}],"hr":[{"v":1,"t":"Dakle, budući da imamo ta obećanja, očistimo se, ljubljeni, od svake ljage tijela i duha te dovršimo posvećenje u strahu Božjemu."},{"v":2,"t":"Shvatite nas! Nikomu nismo nanijeli nepravde, nikoga nismo upropastili, nikoga zakinuli."},{"v":3,"t":"Ne govorim da osudim. Ta rekoh već: u srcima ste našim te umiremo i živimo zajedno."},{"v":4,"t":"Veliko je moje pouzdanje u vas, uvelike se vama ponosim. Pun sam utjehe, obilujem radošću uza svu nevolju našu."},{"v":5,"t":"Doista, i kada dođosmo u Makedoniju, nikakva spokoja nije imalo tijelo naše, nego nevolje odasvud: izvana borbe, iznutra strepnje."},{"v":6,"t":"Ali Bog, tješitelj poniznih, utješi nas dolaskom Titovim."},{"v":7,"t":"Ne samo dolaskom njegovim, nego i utjehom kojom se utješi zbog vas: obavijesti nas o vašoj čežnji, vašem jadikovanju, vašoj žarkoj ljubavi prema meni tako da se još većma obradovah."},{"v":8,"t":"Doista, ako sam vas i ožalostio onom poslanicom, nije mi žao; ako mi i bijaše žao - vidim uistinu da vas je ta poslanica makar i načas ožalostila -"},{"v":9,"t":"sad se radujem, ne što ste se ožalostili, nego što ste se ožalostili na obraćenje. Jer ožalostili ste se po Božju te zbog nas ni u čemu niste štetovali."},{"v":10,"t":"Jer žalost po Božju rađa neopozivo spasonosnim obraćenjem, a žalost svjetovna rađa smrću."},{"v":11,"t":"Gle, doista baš to što ste se po Božju ožalostili, kolikom gorljivošću urodi među vama, pa opravdavanjem, pa ogorčenjem, pa strahom, pa čežnjom, pa revnošću, pa kažnjavanjem. Svime ste time pokazali da ste u onome nedužni."},{"v":12,"t":"Ako sam vam dakle pisao, nisam to zbog uvreditelja ni zbog uvrijeđenoga, nego zbog toga da vam se očituje vaša gorljivost za nas pred Bogom."},{"v":13,"t":"To nas je utješilo. A povrh te naše utjehe još se mnogo više obradovasmo zbog radosti Titove jer svi vi okrijepiste duh njegov."},{"v":14,"t":"Doista, ako sam mu se što vama pohvalio, ne postidjeh se, nego kao što smo po istini vama govorili, tako je istina bila i pohvala naša pred Titom."},{"v":15,"t":"I njegovo je srce prema vama još nježnije kad se sjeti poslušnosti svih vas, kako ga sa strahom i trepetom primiste."},{"v":16,"t":"Radujem se što se u svemu mogu pouzdati u vas."}]},"8":{"fa":[{"v":1,"t":"لیکن‌ای برادران شما را مطلع می‌سازیم ازفیض خدا که به کلیساهای مکادونیه عطاشده است."},{"v":2,"t":"زیرا در امتحان شدید زحمت، فراوانی خوشی ایشان ظاهر گردید و از زیادتی فقر ایشان، دولت سخاوت ایشان افزوده شد."},{"v":3,"t":"زیرا که شاهد هستم که بحسب طاقت بلکه فوق از طاقت خویش به رضامندی تمام،"},{"v":4,"t":"التماس بسیار نموده، این نعمت و شراکت در خدمت مقدسین را از ما طلبیدند."},{"v":5,"t":"و نه‌چنانکه امیدداشتیم، بلکه اول خویشتن را به خداوند و به مابرحسب اراده خدا دادند."},{"v":6,"t":"و از این سبب از تیطس استدعا نمودیم که همچنانکه شروع این نعمت را در میان شما کرد، آن را به انجام هم برساند."},{"v":7,"t":"بلکه چنانکه درهرچیز افزونی دارید، در ایمان و کلام و معرفت وکمال اجتهاد و محبتی که با ما می‌دارید، در این نعمت نیز بیفزایید."},{"v":8,"t":"این را به طریق حکم نمی گویم بلکه به‌سبب اجتهاد دیگران و تااخلاص محبت شما را بیازمایم."},{"v":9,"t":"زیرا که فیض خداوند ما عیسی مسیح را می‌دانید که هرچنددولتمند بود، برای شما فقیر شد تا شما از فقر اودولتمند شوید."},{"v":10,"t":"و در این، رای می‌دهم زیرا که این شما را شایسته است، چونکه شما در سال گذشته، نه در عمل فقط بلکه در اراده نیز اول ازهمه شروع کردید."},{"v":11,"t":"اما الحال عمل را به انجام رسانید تا چنانکه دلگرمی در اراده بود، انجام عمل نیز برحسب آنچه دارید بشود."},{"v":12,"t":"زیراهرگاه دلگرمی باشد، مقبول می‌افتد، بحسب آنچه کسی دارد نه بحسب آنچه ندارد."},{"v":13,"t":"و نه اینکه دیگران را راحت و شما را زحمت باشد، بلکه به طریق مساوات تا در حال، زیادتی شمابرای کمی ایشان بکار آید؛"},{"v":14,"t":"و تا زیادتی ایشان بجهت کمی شما باشد و مساوات بشود."},{"v":15,"t":"چنانکه مکتوب است: «آنکه بسیار جمع کرد، زیادتی نداشت و آنکه اندکی جمع کرد، کمی نداشت."},{"v":16,"t":"اما شکر خداراست که این اجتهاد را برای شما در دل تیطس نهاد."},{"v":17,"t":"زیرا او خواهش ما رااجابت نمود، بلکه بیشتر با اجتهاد بوده، به رضامندی تمام به سوی شما روانه شد."},{"v":18,"t":"و باوی آن برادری را فرستادیم که مدح او در انجیل در تمامی کلیساها است."},{"v":19,"t":"و نه همین فقط بلکه کلیساها نیز او را اختیار کردند تا در این نعمتی که خدمت آن را برای تمجید خداوند و دلگرمی شما می‌کنیم، هم‌سفر مابشود."},{"v":20,"t":"چونکه اجتناب می‌کنیم که مبادا کسی ما را ملامت کند درباره این سخاوتی که خادمان آن هستیم."},{"v":21,"t":"زیرا که نه درحضور خداوند فقط، بلکه در نظر مردم نیزچیزهای نیکو را تدارک می‌بینیم."},{"v":22,"t":"و با ایشان برادر خود را نیز فرستادیم که مکرر در اموربسیار او را با اجتهاد یافتیم و الحال به‌سبب اعتماد کلی که بر شما می‌دارد، بیشتر با اجتهاداست."},{"v":23,"t":"هرگاه درباره تیطس (بپرسند)، او درخدمت شما رفیق و همکار من است؛ و اگر درباره برادران ما، ایشان رسل کلیساها و جلال مسیح می‌باشند."},{"v":24,"t":"پس دلیل محبت خود و فخر ما را درباره شما در حضور کلیساها به ایشان ظاهرنمایید."}],"en":[{"v":1,"t":"Moreover, brothers, we make known to you the grace of God which has been given in the assemblies of Macedonia,"},{"v":2,"t":"how in a severe ordeal of affliction, the abundance of their joy and their deep poverty abounded to the riches of their generosity."},{"v":3,"t":"For according to their power, I testify, yes and beyond their power, they gave of their own accord,"},{"v":4,"t":"begging us with much entreaty to receive this grace and the fellowship in the service to the saints."},{"v":5,"t":"This was not as we had expected, but first they gave their own selves to the Lord, and to us through the will of God."},{"v":6,"t":"So we urged Titus, that as he had made a beginning before, so he would also complete in you this grace."},{"v":7,"t":"But as you abound in everything—in faith, utterance, knowledge, all earnestness, and in your love to us—see that you also abound in this grace."},{"v":8,"t":"I speak not by way of commandment, but as proving through the earnestness of others the sincerity also of your love."},{"v":9,"t":"For you know the grace of our Lord Jesus Christ, that though he was rich, yet for your sakes he became poor, that you through his poverty might become rich."},{"v":10,"t":"I give advice in this: it is expedient for you who were the first to start a year ago, not only to do, but also to be willing."},{"v":11,"t":"But now complete the doing also, that as there was the readiness to be willing, so there may be the completion also out of your ability."},{"v":12,"t":"For if the readiness is there, it is acceptable according to what you have, not according to what you don’t have."},{"v":13,"t":"For this is not that others may be eased and you distressed,"},{"v":14,"t":"but for equality. Your abundance at this present time supplies their lack, that their abundance also may become a supply for your lack, that there may be equality."},{"v":15,"t":"As it is written, “He who gathered much had nothing left over, and he who gathered little had no lack.”"},{"v":16,"t":"But thanks be to God, who puts the same earnest care for you into the heart of Titus."},{"v":17,"t":"For he indeed accepted our exhortation, but being himself very earnest, he went out to you of his own accord."},{"v":18,"t":"We have sent together with him the brother whose praise in the Good News is known throughout all the assemblies."},{"v":19,"t":"Not only so, but he was also appointed by the assemblies to travel with us in this grace, which is served by us to the glory of the Lord himself, and to show our readiness."},{"v":20,"t":"We are avoiding this, that any man should blame us concerning this abundance which is administered by us."},{"v":21,"t":"Having regard for honorable things, not only in the sight of the Lord, but also in the sight of men."},{"v":22,"t":"We have sent with them our brother whom we have many times proved earnest in many things, but now much more earnest, by reason of the great confidence which he has in you."},{"v":23,"t":"As for Titus, he is my partner and fellow worker for you. As for our brothers, they are the apostles of the assemblies, the glory of Christ."},{"v":24,"t":"Therefore show the proof of your love to them before the assemblies, and of our boasting on your behalf."}],"hr":[{"v":1,"t":"Priopćujemo vam, braćo, milost Božju koja je dana crkvama makedonskim:"},{"v":2,"t":"unatoč mnogim kušnjama i nevoljama izobilna njihova radost i skrajnje siromaštvo preli se u bogatstvo darežljivosti."},{"v":3,"t":"Svjedočim uistinu: oni su nas dragovoljno - po svojim mogućnostima i preko mogućnosti -"},{"v":4,"t":"veoma usrdno molili za milost zajedništva u ovom posluživanju svetih."},{"v":5,"t":"I to ne samo kako se nadasmo, nego same sebe predadoše najprvo Gospodinu, a onda nama, po volji Božjoj."},{"v":6,"t":"Zato zamolismo Tita da kao što je započeo, tako i dovrši među vama i to djelo darežljivosti."},{"v":7,"t":"Stoga kao što se u svemu odlikujete - u vjeri, i riječi, i spoznanju, i svakoj gorljivosti, i u ljubavi svojoj prema nama - odlikujte se i u ovoj darežljivosti."},{"v":8,"t":"Ne zapovijedam, nego gorljivošću drugih prokušavam istinitost vaše ljubavi."},{"v":9,"t":"Ta poznate darežljivost Gospodina našega Isusa Krista! Premda bogat, radi vas posta siromašan, da se vi njegovim siromaštvom obogatite."},{"v":10,"t":"Time dajem samo savjet: to doista dolikuje vama koji već prošle godine prvi to započeste, ne samo činom nego i odlukom."},{"v":11,"t":"Sada dovršite to djelo da kao što spremno odlučiste, tako prema mogućnostima i dovršite."},{"v":12,"t":"Jer ima li spremnosti, mila je po onom što ima, a ne po onom čega nema."},{"v":13,"t":"Ne dakako: drugima olakšica, vama oskudica, nego - jednakost!"},{"v":14,"t":"U sadašnjem trenutku vaš suvišak za njihovu oskudicu da jednom njihov suvišak bude za vašu oskudicu - te bude jednakost,"},{"v":15,"t":"kao što je pisano: Nije ništa preteklo onome koji bijaše nakupio mnogo, a niti je nedostajalo onome koji bijaše nakupio manje."},{"v":16,"t":"A hvala Bogu koji je stavio jednaku gorljivost za vas u srce Titovo."},{"v":17,"t":"On je prihvatio i molbu, ali budući da je veoma revan, otiđe k vama i dragovoljno."},{"v":18,"t":"S njime pak šaljemo brata kojega s evanđelja slave sve crkve."},{"v":19,"t":"Štoviše, crkve ga izabraše za našeg suputnika u ovom djelu darežljivosti kojemu služimo - na slavu samoga Gospodina i na našu želju"},{"v":20,"t":"kako bismo izbjegli da nas tko ne prekori zbog ovog obilja kojim raspolažemo."},{"v":21,"t":"Doista, revno nastojimo oko dobra ne samo pred Gospodinom nego i pred ljudima."},{"v":22,"t":"Šaljemo s njima i našega brata koji je, kako smo u mnogome često iskusili, gorljiv, a sada je još mnogo gorljiviji zbog velikoga pouzdanja u vas."},{"v":23,"t":"A Tito? Moj je drug i suradnik za vas. A braća naša? Poslanici su crkava, slava Kristova."},{"v":24,"t":"Pružite im dakle pred crkvama dokaz svoje ljubavi i toga da se s pravom vama ponosimo."}]},"9":{"fa":[{"v":1,"t":"زیرا که در خصوص این خدمت مقدسین، زیادتی می‌باشد که به شما بنویسم."},{"v":2,"t":"چونکه دلگرمی شما را می‌دانم که درباره آن بجهت شما به اهل مکادونیه فخر می‌کنم که ازسال گدشته اهل اخائیه مستعد شده‌اند و غیرت شما اکثر ایشان را تحریض نموده است."},{"v":3,"t":"امابرادران را فرستادم که مبادا فخر ما درباره شما دراین خصوص باطل شود تا چنانکه گفته‌ام، مستعدشوید."},{"v":4,"t":"مبادا اگر اهل مکادونیه با من آیند و شمارا نامستعد یابند، نمی گویم شما بلکه ما از این اعتمادی که به آن فخر کردیم، خجل شویم،"},{"v":5,"t":"پس لازم دانستم که برادران را نصیحت کنم تاقبل از ما نزد شما آیند و برکت موعود شما را مهیاسازند تا حاضر باشد، از راه برکت نه از راه طمع."},{"v":6,"t":"اما خلاصه این است، هرکه با بخیلی کارد، بابخیلی هم درو کند و هرکه با برکت کارد، با برکت نیز درو کند."},{"v":7,"t":"اما هرکس بطوری که در دل خوداراده نموده است بکند، نه به حزن و اضطرار، زیراخدا بخشنده خوش را دوست می‌دارد."},{"v":8,"t":"ولی خدا قادر است که هر نعمتی را برای شما بیفزایدتا همیشه در هر امری کفایت کامل داشته، برای هر عمل نیکو افزوده شوید."},{"v":9,"t":"چنانکه مکتوب است که «پاشید و به فقرا داد و عدالتش تا به ابدباقی می‌ماند»."},{"v":10,"t":"اما او که برای برزگر بذر و برای خورنده نان را آماده می‌کند، بذر شما را آماده کرده، خواهد افزود و ثمرات عدالت شما را مزید خواهد کرد."},{"v":11,"t":"تا آنکه در هرچیز دولتمند شده، کمال سخاوت را بنمایید که آن منشا شکر خدابوسیله ما می‌باشد."},{"v":12,"t":"زیرا که به‌جا آوردن این خدمت، نه فقط حاجات مقدسین را رفع می‌کند، بلکه سپاس خدا را نیز بسیار می‌افزاید."},{"v":13,"t":"و ازدلیل این خدمت، خدا را تمجید می‌کنند به‌سبب اطاعت شما در اعتراف انجیل مسیح و سخاوت بخشش شما برای ایشان و همگان."},{"v":14,"t":"و ایشان به‌سبب افزونی فیض خدایی که بر شماست، دردعای خود مشتاق شما می‌باشند."},{"v":15,"t":"خدا را برای عطای ما لاکلام او شکر باد."}],"en":[{"v":1,"t":"It is indeed unnecessary for me to write to you concerning the service to the saints,"},{"v":2,"t":"for I know your readiness, of which I boast on your behalf to those of Macedonia, that Achaia has been prepared for the past year. Your zeal has stirred up very many of them."},{"v":3,"t":"But I have sent the brothers so that our boasting on your behalf may not be in vain in this respect, that, just as I said, you may be prepared,"},{"v":4,"t":"lest by any means, if anyone from Macedonia comes there with me and finds you unprepared, we (to say nothing of you) would be disappointed in this confident boasting."},{"v":5,"t":"I thought it necessary therefore to entreat the brothers that they would go before to you and arrange ahead of time the generous gift that you promised before, that the same might be ready as a matter of generosity, and not of greediness."},{"v":6,"t":"Remember this: he who sows sparingly will also reap sparingly. He who sows bountifully will also reap bountifully."},{"v":7,"t":"Let each man give according as he has determined in his heart, not grudgingly or under compulsion, for God loves a cheerful giver."},{"v":8,"t":"And God is able to make all grace abound to you, that you, always having all sufficiency in everything, may abound to every good work."},{"v":9,"t":"As it is written, “He has scattered abroad. He has given to the poor. His righteousness remains forever.”"},{"v":10,"t":"Now may he who supplies seed to the sower and bread for food, supply and multiply your seed for sowing, and increase the fruits of your righteousness,"},{"v":11,"t":"you being enriched in everything for all generosity, which produces thanksgiving to God through us."},{"v":12,"t":"For this service of giving that you perform not only makes up for lack among the saints, but abounds also through much giving of thanks to God,"},{"v":13,"t":"seeing that through the proof given by this service, they glorify God for the obedience of your confession to the Good News of Christ and for the generosity of your contribution to them and to all,"},{"v":14,"t":"while they themselves also, with supplication on your behalf, yearn for you by reason of the exceeding grace of God in you."},{"v":15,"t":"Now thanks be to God for his unspeakable gift!"}],"hr":[{"v":1,"t":"A o posluživanju svetih suvišno je da vam pišem."},{"v":2,"t":"Ta poznajem vašu spremnost s koje se vama ponosim pred Makedoncima: “Ahaja je spremna od prošle godine.” I vaša gorljivost potaknu mnoge."},{"v":3,"t":"Ipak šaljem braću da se u tome pogledu ne opovrgne što se vama ponosimo; da budete spremni kao što sam tvrdio te se -"},{"v":4,"t":"ako sa mnom dođu Makedonci i nađu vas nespremne - ne osramotimo s preuzetnosti mi, da ne kažemo vi."},{"v":5,"t":"Smatrao sam dakle potrebnim zamoliti braću da unaprijed pođu k vama i da pripreme vaš još prije obećani dar te bude pripravan - kao dar darežljivosti, a ne škrtosti."},{"v":6,"t":"Ta eno: tko sije oskudno, oskudno će i žeti; a tko sije obilato, obilato će i žeti."},{"v":7,"t":"Svatko neka dade kako je srcem odlučio; ne sa žalošću ili na silu jer Bog ljubi vesela darivatelja."},{"v":8,"t":"A Bog vas može obilato obdariti svakovrsnim darom da u svemu svagda imate svega dovoljno za se i izobilno za svako dobro djelo -"},{"v":9,"t":"kao što je pisano: Rasipno dijeli, daje sirotinji, pravednost njegova ostaje dovijeka."},{"v":10,"t":"A onaj koji pribavlja sjeme sijaču i kruh za jelo, pribavit će i umnožiti sjeme vaše i povećati plodove pravednosti vaše."},{"v":11,"t":"Tako ćete se u svemu obogatiti za svakovrsnu darežljivost koja se, našim posredovanjem, izvija u zahvalnicu Bogu."},{"v":12,"t":"Jer ovo bogoslužno posluživanje ne samo da podmiruje oskudicu svetih nego se i obilno prelijeva u mnoge zahvalnice Bogu."},{"v":13,"t":"Osvjedočeni ovim posluživanjem, slave Boga zbog vašega pokornog ispovijedanja evanđelja Kristova i zbog velikodušnog zajedništva prema njima i prema svima."},{"v":14,"t":"A moleći se za vas, čeznu za vama zbog preobilne milosti Božje na vama."},{"v":15,"t":"Hvala Bogu na njegovu neizrecivom daru!"}]},"10":{"fa":[{"v":1,"t":"اما من خود، پولس، که چون در میان شما حاضر بودم، فروتن بودم، لیکن وقتی که غایب هستم، با شما جسارت می‌کنم، ازشما به حلم و رافت مسیح استدعا دارم"},{"v":2,"t":"والتماس می‌کنم که چون حاضر شوم، جسارت نکنم بدان اعتمادی که گمان می‌برم که جرات خواهم کرد با آنانی که می‌پندارند که ما به طریق جسم رفتار می‌کنیم."},{"v":3,"t":"زیرا هرچند در جسم رفتار می‌کنیم، ولی به قانون جسمی جنگ نمی نماییم."},{"v":4,"t":"زیرا اسلحه جنگ ما جسمانی نیست بلکه نزد خدا قادر است برای انهدام قلعه‌ها،"},{"v":5,"t":"که خیالات و هر بلندی را که خود را به خلاف معرفت خدا می‌افرازد، به زیر می‌افکنیم وهر فکری را به اطاعت مسیح اسیر می‌سازیم."},{"v":6,"t":"ومستعد هستیم که از هر معصیت انتقام جوییم وقتی که اطاعت شما کامل شود."},{"v":7,"t":"آیا به صورت ظاهری نظر می‌کنید؟ اگر کسی بر خود اعتماد دارد که از آن مسیح است، این را نیز از خود بداند که چنانکه او از آن مسیح است، ما نیز همچنان از آن مسیح هستیم."},{"v":8,"t":"زیراهرچند زیاده هم فخر بکنم درباره اقتدار خود که خداوند آن را برای بنا نه برای خرابی شما به ماداده است، خجل نخواهم شد،"},{"v":9,"t":"که مبادا معلوم شود که شما را به رساله‌ها می‌ترسانم."},{"v":10,"t":"زیرامی گویند: «رساله های او گران و زورآور است، لیکن حضور جسمی او ضعیف و سخنش حقیر.»"},{"v":11,"t":"چنین شخص بداند که چنانکه در کلام به رساله‌ها در غیاب هستیم، همچنین نیز در فعل درحضور خواهیم بود."},{"v":12,"t":"زیرا جرات نداریم که خود را از کسانی که خویشتن را مدح می‌کنند بشماریم، یا خود را باایشان مقابله نماییم؛ بلکه ایشان چون خود را باخود می‌پیمایند و خود را به خود مقابله می‌نمایند، دانا نیستند."},{"v":13,"t":"اما ما زیاده از اندازه فخر نمی کنیم، بلکه بحسب اندازه آن قانونی که خدا برای ما پیمود، و آن اندازه‌ای است که به شمانیز می‌رسد."},{"v":14,"t":"زیرا از حد خود تجاوز نمی کنیم که گویا به شما نرسیده باشیم، چونکه در انجیل مسیح به شما هم رسیده‌ایم."},{"v":15,"t":"و از اندازه خودنگذشته در محنتهای دیگران فخر نمی نماییم، ولی امید داریم که چون ایمان شما افزون شود، در میان شما بحسب قانون خود بغایت افزوده خواهیم شد."},{"v":16,"t":"تا اینکه در مکانهای دورتر ازشما هم بشارت دهیم و در امور مهیا شده به قانون دیگران فخر نکنیم."},{"v":17,"t":"اما هرکه فخر نماید، به خداوند فخر بنماید."},{"v":18,"t":"زیرا نه آنکه خود را مدح کند مقبول افتد بلکه آن را که خداوند مدح نماید."}],"en":[{"v":1,"t":"Now I Paul, myself, entreat you by the humility and gentleness of Christ, I who in your presence am lowly among you, but being absent am bold toward you."},{"v":2,"t":"Yes, I beg you that I may not, when present, show courage with the confidence with which I intend to be bold against some, who consider us to be walking according to the flesh."},{"v":3,"t":"For though we walk in the flesh, we don’t wage war according to the flesh;"},{"v":4,"t":"for the weapons of our warfare are not of the flesh, but mighty before God to the throwing down of strongholds,"},{"v":5,"t":"throwing down imaginations and every high thing that is exalted against the knowledge of God and bringing every thought into captivity to the obedience of Christ,"},{"v":6,"t":"and being in readiness to avenge all disobedience when your obedience is made full."},{"v":7,"t":"Do you look at things only as they appear in front of your face? If anyone trusts in himself that he is Christ’s, let him consider this again with himself, that even as he is Christ’s, so we also are Christ’s."},{"v":8,"t":"For even if I boast somewhat abundantly concerning our authority, which the Lord gave for building you up and not for casting you down, I will not be ashamed,"},{"v":9,"t":"that I may not seem as if I desire to terrify you by my letters."},{"v":10,"t":"For, “His letters”, they say, “are weighty and strong, but his bodily presence is weak, and his speech is despised.”"},{"v":11,"t":"Let such a person consider this, that what we are in word by letters when we are absent, such are we also in deed when we are present."},{"v":12,"t":"For we are not bold to number or compare ourselves with some of those who commend themselves. But they themselves, measuring themselves by themselves, and comparing themselves with themselves, are without understanding."},{"v":13,"t":"But we will not boast beyond proper limits, but within the boundaries with which God appointed to us, which reach even to you."},{"v":14,"t":"For we don’t stretch ourselves too much, as though we didn’t reach to you. For we came even as far as to you with the Good News of Christ,"},{"v":15,"t":"not boasting beyond proper limits in other men’s labors, but having hope that as your faith grows, we will be abundantly enlarged by you in our sphere of influence,"},{"v":16,"t":"so as to preach the Good News even to the parts beyond you, not to boast in what someone else has already done."},{"v":17,"t":"But “he who boasts, let him boast in the Lord.”"},{"v":18,"t":"For it isn’t he who commends himself who is approved, but whom the Lord commends."}],"hr":[{"v":1,"t":"Ja, Pavao, osobno vas zaklinjem blagošću i obazrivošću Kristovom - ja koji sam licem u lice među vama “skroman”, a nenazočan prema vama “odvažan” -"},{"v":2,"t":"molim da, jednom nazočan, ne moram biti odvažan smionošću kojom se kanim osmjeliti protiv nekih što smatraju da mi po tijelu živimo."},{"v":3,"t":"Jer iako živimo u tijelu, ne vojujemo po tijelu."},{"v":4,"t":"Ta oružje našega vojevanja nije tjelesno, nego božanski snažno za rušenje utvrda. Obaramo mudrovanja"},{"v":5,"t":"i svaku oholost koja se podiže protiv spoznanja Boga i zarobljujemo svaki um na pokornost Kristu;"},{"v":6,"t":"i spremni smo kazniti svaku nepokornost čim bude savršena vaša pokornost."},{"v":7,"t":"Gledajte što je očito! Ako je tko uvjeren da je “Kristov”, neka sam ponovno promisli ovo: kako je on Kristov, tako smo i mi."},{"v":8,"t":"Kad bih se doista i malo više pohvalio našom vlašću - koju nam Gospodin dade za vaše izgrađivanje, a ne rušenje - ne bih se morao stidjeti."},{"v":9,"t":"Samo da se ne bi činilo kao da vas zastrašujem poslanicama!"},{"v":10,"t":"Jer “poslanice su, kaže, stroge i snažne, ali tjelesna nazočnost nemoćna i riječ bezvrijedna”."},{"v":11,"t":"Takav neka promisli ovo: kakvi smo nenazočni riječju u poslanicama, takvi smo i nazočni djelom."},{"v":12,"t":"Ne usuđujemo se, doista, izjednačiti ili usporediti s nekima koji sami sebe preporučuju, ali nisu razumni jer sami sebe sobom mjere i sami sebe sa sobom uspoređuju."},{"v":13,"t":"Mi se pak nećemo hvaliti u bezmjerje, nego po mjeri, mjerilu što nam ga odmjeri Bog kao mjeru: doprijeti sve do vas."},{"v":14,"t":"Jer mi ne posežemo preko svoga, kao da još nismo stigli do vas. Ta prvi doista doprijesmo do vas s evanđeljem Kristovim."},{"v":15,"t":"Ne hvalimo se u bezmjerje, tuđim naporima. A nadamo se da ćemo s uzrastom vaše vjere među vama i mi - po našem mjerilu - prerasti u izobilje:"},{"v":16,"t":"i preko vaših granica navijestiti evanđelje, a ne hvastati se onim što je već učinjeno na tuđem području."},{"v":17,"t":"Tko se hvali, u Gospodinu neka se hvali."},{"v":18,"t":"Ta nije prokušan tko sam sebe preporučuje, nego koga preporučuje Gospodin."}]},"11":{"fa":[{"v":1,"t":"کاشکه مرا در اندک جهالتی متحمل شوید و متحمل من هم می‌باشید."},{"v":2,"t":"زیراکه من بر شما غیور هستم به غیرت الهی؛ زیرا که شما را به یک شوهر نامزد ساختم تا باکره‌ای عفیفه به مسیح سپارم."},{"v":3,"t":"لیکن می‌ترسم که چنانکه مار به مکر خود حوا را فریفت، همچنین خاطرشما هم از سادگی‌ای که در مسیح است، فاسدگردد."},{"v":4,"t":"زیرا هرگاه آنکه آمد، وعظ می‌کرد به عیسای دیگر، غیر از آنکه ما بدو موعظه کردیم، یا شما روحی دیگر را جز آنکه یافته بودید، یاانجیلی دیگر را سوای آنچه قبول کرده بودیدمی پذیرفتید، نیکو می‌کردید که متحمل می‌شدید."},{"v":5,"t":"زیرا مرا یقین است که از بزرگترین رسولان هرگز کمتر نیستم."},{"v":6,"t":"اما هرچند در کلام نیز امی باشم، لیکن در معرفت نی. بلکه در هر امری نزدهمه کس به شما آشکار گردیدیم."},{"v":7,"t":"آیا گناه کردم که خود را ذلیل ساختم تا شما سرافراز شوید دراینکه به انجیل خدا شما را مفت بشارت دادم؟"},{"v":8,"t":"کلیساهای دیگر را غارت نموده، اجرت گرفتم تا شما را خدمت نمایم و چون به نزد شما حاضربوده، محتاج شدم، بر هیچ‌کس بار ننهادم."},{"v":9,"t":"زیرابرادرانی که از مکادونیه آمدند، رفع حاجت مرانمودند و در هرچیز از بار نهادن بر شما خود رانگاه داشته و خواهم داشت."},{"v":10,"t":"به راستی مسیح که در من است قسم که این فخر در نواحی اخائیه از من گرفته نخواهد شد."},{"v":11,"t":"از چه سبب؟ آیا ازاینکه شما را دوست نمی دارم؟ خدا می‌داند!"},{"v":12,"t":"لیکن آنچه می‌کنم هم خواهم کرد تا از جویندگان فرصت، فرصت را منقطع سازم تا درآنچه فخر می‌کنند، مثل ما نیز یافت شوند."},{"v":13,"t":"زیرا که چنین اشخاص رسولان کذبه و عمله مکار هستند که خویشتن را به رسولان مسیح مشابه می‌سازند."},{"v":14,"t":"و عجب نیست، چونکه خودشیطان هم خویشتن را به فرشته نور مشابه می‌سازد."},{"v":15,"t":"پس امر بزرگ نیست که خدام وی خویشتن را به خدام عدالت مشابه سازند که عاقبت ایشان برحسب اعمالشان خواهد بود."},{"v":16,"t":"باز می‌گویم، کسی مرا بی‌فهم نداند والا مراچون بی‌فهمی بپذیرید تا من نیز اندکی افتخارکنم."},{"v":17,"t":"آنچه می‌گویم از جانب خداوندنمی گویم، بلکه از راه بی‌فهمی در این اعتمادی که فخر ما است."},{"v":18,"t":"چونکه بسیاری از طریق جسمانی فخر می‌کنند، من هم فخر می‌نمایم."},{"v":19,"t":"زیرا چونکه خود فهیم هستید، بی‌فهمان را به خوشی متحمل می‌باشید."},{"v":20,"t":"زیرا متحمل می‌شوید هرگاه کسی شما را غلام سازد، یا کسی شما را فرو خورد، یا کسی شما را گرفتار کند، یاکسی خود را بلند سازد، یا کسی شما را بر رخسارطپانچه زند."},{"v":21,"t":"از روی استحقار می‌گویم که گویاما ضعیف بوده‌ایم."},{"v":22,"t":"آیاعبرانی هستند؟ من نیز هستم! اسرائیلی هستند؟ من نیز هستم! از ذریت ابراهیم هستند؟ من نیزمی باشم!"},{"v":23,"t":"آیا خدام مسیح هستند؟ چون دیوانه حرف می‌زنم، من بیشتر هستم! در محنتهاافزونتر، در تازیانه‌ها زیادتر، در زندانها بیشتر، در مرگها مکرر."},{"v":24,"t":"از یهودیان پنج مرتبه از چهل یک کم تازیانه خوردم."},{"v":25,"t":"سه مرتبه مرا چوب زدند؛ یک دفعه سنگسار شدم؛ سه کرت شکسته کشتی شدم؛ شبانه‌روزی در دریا بسر بردم؛"},{"v":26,"t":"درسفرها بارها؛ در خطرهای نهرها؛ در خطرهای دزدان؛ در خطرها از قوم خود و در خطرها ازامت‌ها؛ در خطرها در شهر؛ در خطرها دربیابان؛ در خطرها در دریا؛ در خطرها در میان برادران کذبه؛"},{"v":27,"t":"در محنت و مشقت، در بی‌خوابیها بارها؛ در گرسنگی و تشنگی، در روزه‌ها بارها؛ در سرماو عریانی."},{"v":28,"t":"بدون آنچه علاوه بر اینها است، آن باری که هر روزه بر من است، یعنی اندیشه برای همه کلیساها."},{"v":29,"t":"کیست ضعیف که من ضعیف نمی شوم؟ که لغزش می‌خورد که من نمی سوزم؟"},{"v":30,"t":"اگر فخر می‌باید کرد از آنچه به ضعف من تعلق دارد، فخر می‌کنم."},{"v":31,"t":"خدا و پدر عیسی مسیح خداوند که تا به ابد متبارک است، می‌داند که دروغ نمی گویم."},{"v":32,"t":"در دمشق، والی حارث پادشاه، شهر دمشقیان را برای گرفتن من محافظت می‌نمود."},{"v":33,"t":"و مرا از دریچه‌ای در زنبیلی از باره قلعه پایین کردند و از دستهای وی رستم."}],"en":[{"v":1,"t":"I wish that you would bear with me in a little foolishness, but indeed you do bear with me."},{"v":2,"t":"For I am jealous over you with a godly jealousy. For I promised you in marriage to one husband, that I might present you as a pure virgin to Christ."},{"v":3,"t":"But I am afraid that somehow, as the serpent deceived Eve in his craftiness, so your minds might be corrupted from the simplicity that is in Christ."},{"v":4,"t":"For if he who comes preaches another Jesus whom we didn’t preach, or if you receive a different spirit which you didn’t receive, or a different “good news” which you didn’t accept, you put up with that well enough."},{"v":5,"t":"For I reckon that I am not at all behind the very best apostles."},{"v":6,"t":"But though I am unskilled in speech, yet I am not unskilled in knowledge. No, in every way we have been revealed to you in all things."},{"v":7,"t":"Or did I commit a sin in humbling myself that you might be exalted, because I preached to you God’s Good News free of charge?"},{"v":8,"t":"I robbed other assemblies, taking wages from them that I might serve you."},{"v":9,"t":"When I was present with you and was in need, I wasn’t a burden on anyone, for the brothers, when they came from Macedonia, supplied the measure of my need. In everything I kept myself from being burdensome to you, and I will continue to do so."},{"v":10,"t":"As the truth of Christ is in me, no one will stop me from this boasting in the regions of Achaia."},{"v":11,"t":"Why? Because I don’t love you? God knows."},{"v":12,"t":"But what I do, that I will continue to do, that I may cut off opportunity from those who desire an opportunity, that in which they boast, they may be recognized just like us."},{"v":13,"t":"For such men are false apostles, deceitful workers, masquerading as Christ’s apostles."},{"v":14,"t":"And no wonder, for even Satan masquerades as an angel of light."},{"v":15,"t":"It is no great thing therefore if his servants also masquerade as servants of righteousness, whose end will be according to their works."},{"v":16,"t":"I say again, let no one think me foolish. But if so, yet receive me as foolish, that I also may boast a little."},{"v":17,"t":"That which I speak, I don’t speak according to the Lord, but as in foolishness, in this confidence of boasting."},{"v":18,"t":"Seeing that many boast after the flesh, I will also boast."},{"v":19,"t":"For you bear with the foolish gladly, being wise."},{"v":20,"t":"For you bear with a man if he brings you into bondage, if he devours you, if he takes you captive, if he exalts himself, or if he strikes you on the face."},{"v":21,"t":"To my shame, I speak as though we had been weak. Yet in whatever way anyone is bold (I speak in foolishness), I am bold also."},{"v":22,"t":"Are they Hebrews? So am I. Are they Israelites? So am I. Are they the offspring of Abraham? So am I."},{"v":23,"t":"Are they servants of Christ? (I speak as one beside himself.) I am more so: in labors more abundantly, in prisons more abundantly, in stripes above measure, and in deaths often."},{"v":24,"t":"Five times I received forty stripes minus one from the Jews."},{"v":25,"t":"Three times I was beaten with rods. Once I was stoned. Three times I suffered shipwreck. I have been a night and a day in the deep."},{"v":26,"t":"I have been in travels often, perils of rivers, perils of robbers, perils from my countrymen, perils from the Gentiles, perils in the city, perils in the wilderness, perils in the sea, perils among false brothers;"},{"v":27,"t":"in labor and travail, in watchings often, in hunger and thirst, in fastings often, and in cold and nakedness."},{"v":28,"t":"Besides those things that are outside, there is that which presses on me daily: anxiety for all the assemblies."},{"v":29,"t":"Who is weak, and I am not weak? Who is caused to stumble, and I don’t burn with indignation?"},{"v":30,"t":"If I must boast, I will boast of the things that concern my weakness."},{"v":31,"t":"The God and Father of the Lord Jesus Christ, he who is blessed forever more, knows that I don’t lie."},{"v":32,"t":"In Damascus the governor under King Aretas guarded the Damascenes’ city, desiring to arrest me."},{"v":33,"t":"I was let down in a basket through a window by the wall, and escaped his hands."}],"hr":[{"v":1,"t":"O kad biste podnijeli nešto malo bezumlja mojega! Da, podnesite me!"},{"v":2,"t":"Ljubomoran sam doista na vas Božjim ljubomorom: ta zaručih vas s jednim mužem, kao čistu djevicu privedoh vas Kristu."},{"v":3,"t":"Ali se bojim da se - kao što zmija zavede Evu svojom lukavštinom - misli vaše ne pokvare i odmetnu od iskrenosti prema Kristu."},{"v":4,"t":"Uistinu, ako tko dođe i propovijeda drugog Isusa, kojega mi nismo propovijedali - ili ako drugoga Duha primate, kojega niste primili; ili drugo evanđelje, koje niste prigrlili - takva lijepo podnosÄite."},{"v":5,"t":"Smatram, eto, da ni u čemu nisam manji od “nadapostola”."},{"v":6,"t":"Jer ako sam i nevješt u govoru, nisam u znanju; naprotiv, u svemu vam ga i pred svima očitovasmo."},{"v":7,"t":"Ili sam grijeh počinio što sam vam - ponizujući sebe da se vi uzvisite - besplatno navješćivao Božje evanđelje?"},{"v":8,"t":"Druge sam crkve plijenio, od njih primao potporu da bih mogao vama služiti. I dok bijah u vas, premda u oskudici, nikomu nisam bio na teret."},{"v":9,"t":"U oskudici su mi pomogla braća koja dođoše iz Makedonije. U svemu sam se čuvao da vam ne budem težak, a i čuvat ću se."},{"v":10,"t":"Istine mi Kristove u meni, ove mi hvale nitko neće oduzeti u ahajskim krajevima."},{"v":11,"t":"Zašto? Jer vas ne ljubim? Bog znade!"},{"v":12,"t":"A što činim, i dalje ću činiti da izbijem izliku onima koji izliku traže ne bi li se s nama izjednačili u onom čime se hvastaju."},{"v":13,"t":"Jer takvi su ljudi lažni apostoli, himbeni radnici, prerušuju se u apostole Kristove."},{"v":14,"t":"I nikakvo čudo! Ta sam se Sotona prerušuje u anđela svjetla."},{"v":15,"t":"Ništa osobito dakle ako se i službenici njegovi prerušuju u službenike pravednosti. Svršetak će im biti po djelima njihovim."},{"v":16,"t":"Opet velim: da me tko ne bi smatrao bezumnim! Uostalom, primite me makar i kao bezumna da se i ja nešto malo pohvalim."},{"v":17,"t":"Što govorim, ne govorim po Gospodnju, nego kao u bezumlju, u ovoj hvalisavoj smionosti."},{"v":18,"t":"Budući da se mnogi hvale po ljudsku, i ja ću se hvaliti."},{"v":19,"t":"Ta rado podnosÄite bezumne, vi umni!"},{"v":20,"t":"Da, podnosÄite ako vas tko zarobljava, ako vas tko proždire, ako tko otima, ako se tko uznosi, ako vas tko po obrazu bije."},{"v":21,"t":"Na sramotu govorim: bili smo, biva, slabi! Ipak, čime se god tko osmjeljuje - u bezumlju govorim - osmjeljujem se i ja!"},{"v":22,"t":"Hebreji su? I ja sam! Izraelci su? I ja sam! Potomstvo su Abrahamovo? I ja sam!"},{"v":23,"t":"Poslužitelji su Kristovi? Kao mahnit govorim: ja još više! U naporima - preobilno; u tamnicama - preobilno; u batinama - prekomjerno; u smrtnim pogiblima - često."},{"v":24,"t":"Od Židova primio sam pet puta po četrdeset manje jednu."},{"v":25,"t":"Triput sam bio šiban, jednom kamenovan, triput doživio brodolom, jednu noć i dan proveo sam u bezdanu."},{"v":26,"t":"Česta putovanja, pogibli od rijeka, pogibli od razbojnika, pogibli od sunarodnjaka, pogibli od pogana, pogibli u gradu, pogibli u pustinji, pogibli na moru, pogibli od lažne braće;"},{"v":27,"t":"u trudu i naporu, često u nespavanju, u gladu i žeđi, često u postovima, u studeni i golotinji!"},{"v":28,"t":"Osim toga, uz drugo, salijetanje svakodnevno, briga za sve crkve."},{"v":29,"t":"Tko je slab, a ja da ne budem slab? Tko se sablažnjuje, a ja da ne izgaram?"},{"v":30,"t":"Treba li se hvaliti, svojom ću se slabošću hvaliti."},{"v":31,"t":"Bog i Otac Gospodina Isusa, blagoslovljen u vijeke, zna da ne lažem."},{"v":32,"t":"U Damasku namjesnik kralja Arete čuvaše grad damaščanski hoteći me uhvatiti."},{"v":33,"t":"Ali kroz prozor spustiše me u košari preko zida te umakoh njegovim rukama."}]},"12":{"fa":[{"v":1,"t":"لابد است که فخر کنم، هرچند شایسته من نیست. لیکن به رویاها و مکاشفات خداوند می‌آیم."},{"v":2,"t":"شخصی را در مسیح می‌شناسم، چهارده سال قبل از این. آیا در جسم؟ نمی دانم! و آیا بیرون از جسم؟ نمی دانم! خدامی داند. چنین شخصی که تا آسمان سوم ربوده شد."},{"v":3,"t":"و چنین شخص را می‌شناسم، خواه درجسم و خواه جدا از جسم، نمی دانم، خدامی داند،"},{"v":4,"t":"که به فردوس ربوده شد و سخنان ناگفتنی شنید که انسان را جایز نیست به آنها تکلم کند."},{"v":5,"t":"از چنین شخص فخر خواهم کرد، لیکن ازخود جز از ضعفهای خویش فخر نمی کنم."},{"v":6,"t":"زیرااگر بخواهم فخر بکنم، بی‌فهم نمی باشم چونکه راست می‌گویم. لیکن اجتناب می‌کنم مبادا کسی در حق من گمانی برد فوق از آنچه در من بیند یا ازمن شنود."},{"v":7,"t":"و تا آنکه از زیادتی مکاشفات زیاده سرافرازی ننمایم، خاری در جسم من داده شد، فرشته شیطان، تا مرا لطمه زند، مبادا زیاده سرافرازی نمایم."},{"v":8,"t":"و درباره آن از خداوند سه دفعه استدعا نمودم تا از من برود."},{"v":9,"t":"مرا گفت: «فیض من تو را کافی است، زیرا که قوت من درضعف کامل می‌گردد.» پس به شادی بسیار ازضعفهای خود بیشتر فخر خواهم نمود تا قوت مسیح در من ساکن شود."},{"v":10,"t":"بنابراین، از ضعفها ورسوایی‌ها و احتیاجات و زحمات و تنگیهابخاطر مسیح شادمانم، زیرا که چون ناتوانم، آنگاه توانا هستم."},{"v":11,"t":"بی‌فهم شده‌ام. شما مرا مجبور ساختید. زیرا می‌بایست شما مرا مدح کرده باشید، از آنروکه من از بزرگترین رسولان به هیچ وجه کمترنیستم، هرچند هیچ هستم."},{"v":12,"t":"بدرستی که علامات رسول در میان شما با کمال صبر از آیات و معجزات و قوات پدید گشت."},{"v":13,"t":"زیرا کدام چیزاست که در آن از سایر کلیساها قاصر بودید؟ مگراینکه من بر شما بار ننهادم. این بی‌انصافی را از من ببخشید!"},{"v":14,"t":"اینک مرتبه سوم مهیا هستم که نزد شمابیایم و بر شما بار نخواهم نهاد از آنرو که نه مال شما بلکه خود شما را طالبم، زیرا که نمی بایدفرزندان برای والدین ذخیره کنند، بلکه والدین برای فرزندان."},{"v":15,"t":"اما من به‌کمال خوشی برای جانهای شما صرف می‌کنم و صرف کرده خواهم شد. و اگر شما را بیشتر محبت نمایم، آیا کمترمحبت بینم؟"},{"v":16,"t":"اما باشد، من بر شما بار ننهادم بلکه چون حیله گر بودم، شما را به مکر به چنگ آوردم."},{"v":17,"t":"آیا به یکی از آنانی که نزد شمافرستادم، نفع از شما بردم؟"},{"v":18,"t":"به تیطس التماس نمودم و با وی برادر را فرستادم. آیا تیطس از شمانفع برد؟ مگر به یک روح و یک روش رفتارننمودیم؟"},{"v":19,"t":"آیا بعد از این مدت، گمان می‌کنید که نزدشما حجت می‌آوریم؟ به حضور خدا در مسیح سخن می‌گوییم. لیکن همه‌چیز‌ای عزیزان برای بنای شما است."},{"v":20,"t":"زیرا می‌ترسم که چون آیم شما را نه‌چنانکه می‌خواهم بیابم و شما مرا بیابیدچنانکه نمی خواهید که مبادا نزاع و حسد وخشمها و تعصب و بهتان و نمامی و غرور وفتنه‌ها باشد."},{"v":21,"t":"و چون بازآیم، خدای من مرا نزدشما فروتن سازد و ماتم کنم برای بسیاری از آنانی که پیشتر گناه کردند و از ناپاکی و زنا و فجوری که کرده بودند، توبه ننمودند."}],"en":[{"v":1,"t":"It is doubtless not profitable for me to boast, but I will come to visions and revelations of the Lord."},{"v":2,"t":"I know a man in Christ who was caught up into the third heaven fourteen years ago—whether in the body, I don’t know, or whether out of the body, I don’t know; God knows."},{"v":3,"t":"I know such a man (whether in the body, or outside of the body, I don’t know; God knows),"},{"v":4,"t":"how he was caught up into Paradise and heard unspeakable words, which it is not lawful for a man to utter."},{"v":5,"t":"On behalf of such a one I will boast, but on my own behalf I will not boast, except in my weaknesses."},{"v":6,"t":"For if I would desire to boast, I will not be foolish; for I will speak the truth. But I refrain, so that no man may think more of me than that which he sees in me or hears from me."},{"v":7,"t":"By reason of the exceeding greatness of the revelations, that I should not be exalted excessively, a thorn in the flesh was given to me: a messenger of Satan to torment me, that I should not be exalted excessively."},{"v":8,"t":"Concerning this thing, I begged the Lord three times that it might depart from me."},{"v":9,"t":"He has said to me, “My grace is sufficient for you, for my power is made perfect in weakness.” Most gladly therefore I will rather glory in my weaknesses, that the power of Christ may rest on me."},{"v":10,"t":"Therefore I take pleasure in weaknesses, in injuries, in necessities, in persecutions, and in distresses, for Christ’s sake. For when I am weak, then am I strong."},{"v":11,"t":"I have become foolish in boasting. You compelled me, for I ought to have been commended by you, for I am in no way inferior to the very best apostles, though I am nothing."},{"v":12,"t":"Truly the signs of an apostle were worked among you in all perseverance, in signs and wonders and mighty works."},{"v":13,"t":"For what is there in which you were made inferior to the rest of the assemblies, unless it is that I myself was not a burden to you? Forgive me this wrong!"},{"v":14,"t":"Behold, this is the third time I am ready to come to you, and I will not be a burden to you; for I seek not your possessions, but you. For the children ought not to save up for the parents, but the parents for the children."},{"v":15,"t":"I will most gladly spend and be spent for your souls. If I love you more abundantly, am I loved the less?"},{"v":16,"t":"Even so, I myself didn’t burden you. But you might say that being crafty, I caught you with deception."},{"v":17,"t":"Did I take advantage of you by anyone of those whom I have sent to you?"},{"v":18,"t":"I exhorted Titus, and I sent the brother with him. Did Titus take any advantage of you? Didn’t we walk in the same spirit? Didn’t we walk in the same steps?"},{"v":19,"t":"Again, do you think that we are excusing ourselves to you? In the sight of God we speak in Christ. But all things, beloved, are for your edifying."},{"v":20,"t":"For I am afraid that perhaps when I come, I might find you not the way I want to, and that I might be found by you as you don’t desire, that perhaps there would be strife, jealousy, outbursts of anger, factions, slander, whisperings, proud thoughts, or riots,"},{"v":21,"t":"that again when I come my God would humble me before you, and I would mourn for many of those who have sinned before now, and not repented of the uncleanness, sexual immorality, and lustfulness which they committed."}],"hr":[{"v":1,"t":"Hvaliti se treba? Ne koristi doduše ali - dolazim na viđenje i objave Gospodnje."},{"v":2,"t":"Znam čovjeka u Kristu: prije četrnaest godina - da li u tijelu, ne znam; da li izvan tijela, ne znam, Bog zna - taj je bio ponesen do trećeg neba."},{"v":3,"t":"I znam da je taj čovjek - da li u tijelu, da li izvan tijela, ne znam, Bog zna -"},{"v":4,"t":"bio ponesen u raj i čuo neizrecive riječi, kojih čovjek ne smije govoriti."},{"v":5,"t":"Time ću se hvaliti, a samim se sobom neću hvaliti osim slabostima svojim."},{"v":6,"t":"Uistinu, kad bih se i htio hvaliti, ne bih bio bezuman; istinu bih govorio. Ali se uzdržavam da ne bi tko mislio o meni više nego što vidi na meni ili što čuje od mene."},{"v":7,"t":"I da se zbog uzvišenosti objava ne bih uzoholio, dan mi je trn u tijelu, anđeo Sotonin, da me udara da se ne uzoholim."},{"v":8,"t":"Za to sam triput molio Gospodina, da odstupi od mene. A on mi reče:"},{"v":9,"t":"“Dosta ti je moja milost jer snaga se u slabosti usavršuje.” Najradije ću se dakle još više hvaliti svojim slabostima da se nastani u meni snaga Kristova."},{"v":10,"t":"Zato uživam u slabostima, uvredama, poteškoćama, progonstvima, tjeskobama poradi Krista. Jer kad sam slab, onda sam jak."},{"v":11,"t":"Postao sam bezuman! Vi me natjeraste. Ta trebalo je da me vi preporučite jer ni u čemu nisam manji od “nadapostola”, premda nisam ništa."},{"v":12,"t":"Znamenja apostolstva moga ostvarena su među vama u posvemašnjoj postojanosti: znakovima i čudesima i silnim djelima."},{"v":13,"t":"Ta u čemu ste to manji od drugih crkava, osim što vam ja nisam bio na teret? Oprostite mi ovu “nepravdu”."},{"v":14,"t":"Evo, spremam se treći put doći k vama i neću vam biti na teret jer ne ištem vaše, nego vas. Djeca doista nisu dužna stjecati roditeljima, nego roditelji djeci."},{"v":15,"t":"A ja ću najradije trošiti i istrošiti se za duše vaše. Ako vas više ljubim, zar da budem manje ljubljen?"},{"v":16,"t":"Ali neka! Ja vas nisam opterećivao, nego, “lukav” kako jesam, “na prijevaru vas uhvatih”."},{"v":17,"t":"Da vas možda nisam zakinuo po kome od onih koje poslah k vama?"},{"v":18,"t":"Zamolio sam Tita i poslao s njime brata. Da vas možda Tit nije u čemu zakinuo? Zar nismo hodili u istom duhu? I istim stopama?"},{"v":19,"t":"Odavna smatrate da se pred vama branimo. Pred Bogom u Kristu govorimo: sve je to, ljubljeni, za vaše izgrađivanje."},{"v":20,"t":"Bojim se doista da vas kada dođem, možda neću naći kakve bih htio i da ćete vi mene naći kakva ne biste htjeli: da ne bi možda bilo svađa, zavisti, žestina, spletkarenja, klevetanja, došaptavanja, nadimanja, buna;"},{"v":21,"t":"da me opet kada dođem, ne bi ponizio Bog moj kod vas kako ne bih morao oplakivati mnoge koji su prije sagriješili, a nisu se pokajali za nečistoću i bludnost i razvratnost koju počiniše."}]},"13":{"fa":[{"v":1,"t":"این مرتبه سوم نزد شما می‌آیم. به گواهی دو سه شاهد، هر سخن ثابت خواهد شد."},{"v":2,"t":"پیش گفتم و پیش می‌گویم که گویادفعه دوم حاضر بوده‌ام، هرچند الان غایب هستم، آنانی را که قبل از این گناه کردند و همه دیگران را که اگر بازآیم، مسامحه نخواهم نمود."},{"v":3,"t":"چونکه دلیل مسیح را که در من سخن می‌گویدمی جویید که او نزد شما ضعیف نیست بلکه درشما تواناست."},{"v":4,"t":"زیرا هرگاه از ضعف مصلوب گشت، لیکن از قوت خدا زیست می‌کند. چونکه ما نیز در وی ضعیف هستیم، لیکن با او از قوت خدا که به سوی شما است، زیست خواهیم کرد."},{"v":5,"t":"خود را امتحان کنید که در ایمان هستید یا نه. خود را باز‌یافت کنید. آیا خود را نمی شناسید که عیسی مسیح در شما است اگر مردود نیستید؟"},{"v":6,"t":"اما امیدوارم که خواهید دانست که ما مردودنیستیم."},{"v":7,"t":"و از خدا مسالت می‌کنم که شما هیچ بدی نکنید، نه تا ظاهر شود که ما مقبول هستیم، بلکه تا شما نیکویی کرده باشید، هرچند ما گویامردود باشیم."},{"v":8,"t":"زیرا که هیچ نمی توانیم به خلاف راستی عمل نماییم بلکه برای راستی."},{"v":9,"t":"وشادمانیم وقتی که ما ناتوانیم و شما توانایید. و نیزبرای این دعا می‌کنیم که شما کامل شوید."},{"v":10,"t":"ازاینجهت این را در غیاب می‌نویسم تا هنگامی که حاضر شوم، سختی نکنم بحسب آن قدرتی که خداوند بجهت بنا نه برای خرابی به من داده است."},{"v":11,"t":"خلاصه‌ای برادران شاد باشید؛ کامل شوید؛ تسلی پذیرید؛ یک رای و با سلامتی بوده باشید و خدای محبت و سلامتی با شما خواهدبود."},{"v":12,"t":"یکدیگر را به بوسه مقدسانه تحیت نمایید."},{"v":13,"t":"جمیع مقدسان به شما سلام می‌رسانند."}],"en":[{"v":1,"t":"This is the third time I am coming to you. “At the mouth of two or three witnesses shall every word be established.”"},{"v":2,"t":"I have warned previously, and I warn again, as when I was present the second time, so now, being absent, I write to those who have sinned before now and to all the rest that if I come again, I will not spare,"},{"v":3,"t":"seeing that you seek a proof of Christ who speaks in me who is not weak, but is powerful in you."},{"v":4,"t":"For he was crucified through weakness, yet he lives through the power of God. For we also are weak in him, but we will live with him through the power of God toward you."},{"v":5,"t":"Examine your own selves, whether you are in the faith. Test your own selves. Or don’t you know about your own selves, that Jesus Christ is in you?—unless indeed you are disqualified."},{"v":6,"t":"But I hope that you will know that we aren’t disqualified."},{"v":7,"t":"Now I pray to God that you do no evil; not that we may appear approved, but that you may do that which is honorable, though we may seem to have failed."},{"v":8,"t":"For we can do nothing against the truth, but for the truth."},{"v":9,"t":"For we rejoice when we are weak and you are strong. We also pray for this: your becoming perfect."},{"v":10,"t":"For this cause I write these things while absent, that I may not deal sharply when present, according to the authority which the Lord gave me for building up and not for tearing down."},{"v":11,"t":"Finally, brothers, rejoice! Be perfected. Be comforted. Be of the same mind. Live in peace, and the God of love and peace will be with you."},{"v":12,"t":"Greet one another with a holy kiss."},{"v":13,"t":"All the saints greet you."}],"hr":[{"v":1,"t":"Evo treći put idem k vama. Svaka presuda neka počiva na iskazu dvojice ili trojice svjedoka."},{"v":2,"t":"Onima koji su prije sagriješili i svima drugima rekoh već i opet - kao onda drugi put nazočan, tako i sada nenazočan - unaprijed velim: ako opet dođem, neću štedjeti."},{"v":3,"t":"Jer vi tražite dokaz da u meni govori Krist koji prema vama nije nemoćan, nego je snažan među vama."},{"v":4,"t":"I raspet bi, istina, po slabosti, ali živi po snazi Božjoj. I mi smo, istina, slabi u njemu, ali ćemo po snazi Božjoj živjeti s njime za vas."},{"v":5,"t":"Same sebe ispitujte, jeste li u vjeri! Same sebe provjeravajte! Zar ne spoznajete sami sebe: da je Isus Krist u vama? Inače niste pravi."},{"v":6,"t":"A spoznat ćete, nadam se, da smo mi pravi."},{"v":7,"t":"Molimo se Bogu da ne činite nikakva zla; ne da se mi pokažemo pravi, nego da vi dobro činite, pa izašli mi i kao nepravi."},{"v":8,"t":"Ta ništa ne možemo protiv istine, nego samo za istinu."},{"v":9,"t":"Da, radujemo se kad smo mi slabi, a vi jaki. Za to se i molimo, za vaše usavršavanje."},{"v":10,"t":"To vam nenazočan pišem zato da nazočan ne bih morao oštro nastupiti vlašću koju mi Gospodin dade za izgrađivanje, a ne za rušenje."},{"v":11,"t":"Uostalom, braćo, radujte se, usavršujte se, tješite se, složni budite, mir njegujte i Bog ljubavi i mira bit će s vama."},{"v":12,"t":"Pozdravite jedni druge svetim cjelovom. Pozdravljaju vas svi sveti."},{"v":13,"t":"Milost Gospodina Isusa Krista, ljubav Boga i zajedništvo Duha Svetoga sa svima vama!"}]}},"GAL":{"1":{"fa":[{"v":1,"t":"پولس، رسول نه از جانب انسان و نه بوسیله انسان بلکه به عیسی مسیح و خدای پدر که او را از مردگان برخیزانید،"},{"v":2,"t":"و همه برادرانی که بامن می‌باشند، به کلیساهای غلاطیه،"},{"v":3,"t":"فیض و سلامتی از جانب خدای پدر وخداوند ما عیسی مسیح با شما باد؛"},{"v":4,"t":"که خود رابرای گناهان ما داد تا ما را از این عالم حاضر شریربحسب اراده خدا و پدر ما خلاصی بخشد،"},{"v":5,"t":"که او را تا ابدالاباد جلال باد. آمین."},{"v":6,"t":"تعجب می‌کنم که بدین زودی از آن کس که شما را به فیض مسیح خوانده است، برمی گردیدبه سوی انجیلی دیگر،"},{"v":7,"t":"که (انجیل ) دیگر نیست. لکن بعضی هستند که شما را مضطرب می‌سازندو می‌خواهند انجیل مسیح را تبدیل نمایند."},{"v":8,"t":"بلکه هرگاه ما هم یا فرشته‌ای از آسمان، انجیلی غیر از آنکه ما به آن بشارت دادیم به شما رساند، اناتیما باد."},{"v":9,"t":"چنانکه پیش گفتیم، الان هم بازمی گویم: اگر کسی انجیلی غیر از آنکه پذیرفتیدبیاورد، اناتیما باد."},{"v":10,"t":"آیا الحال مردم را در رای خود می‌آورم؟ یا خدا را یا رضامندی مردم را می طلبم؟ اگر تابحال رضامندی مردم رامی خواستم، غلام مسیح نمی بودم."},{"v":11,"t":"اما‌ای برادران شما را اعلام می‌کنم ازانجیلی که من بدان بشارت دادم که به طریق انسان نیست."},{"v":12,"t":"زیرا که من آن را از انسان نیافتم ونیاموختم، مگر به کشف عیسی مسیح."},{"v":13,"t":"زیراسرگذشت سابق مرا در دین یهود شنیده‌اید که برکلیسای خدا بینهایت جفا می‌نمودم و آن راویران می‌ساختم،"},{"v":14,"t":"و در دین یهود از اکثرهمسالان قوم خود سبقت می‌جستم و در تقالیداجداد خود بغایت غیور می‌بودم."},{"v":15,"t":"اما چون خداکه مرا از شکم مادرم برگزید و به فیض خود مراخواند، رضا بدین داد"},{"v":16,"t":"که پسر خود را در من آشکار سازد تا در میان امت‌ها بدو بشارت دهم، در آنوقت با جسم و خون مشورت نکردم،"},{"v":17,"t":"و به اورشلیم هم نزد آنانی که قبل از من رسول بودندنرفتم، بلکه به عرب شدم و باز به دمشق مراجعت کردم."},{"v":18,"t":"پس بعد از سه سال، برای ملاقات پطرس به اورشلیم رفتم و پانزده روز با وی بسر بردم."},{"v":19,"t":"اما از سایر رسولان جز یعقوب برادر خداوندرا ندیدم."},{"v":20,"t":"اما درباره آنچه به شما می‌نویسم، اینک در حضور خدا دروغ نمی گویم."},{"v":21,"t":"بعد از آن به نواحی سوریه و قیلیقیه آمدم."},{"v":22,"t":"و به کلیساهای یهودیه که در مسیح بودند صورت غیرمعروف بودم،"},{"v":23,"t":"جز اینکه شنیده بودند که «آنکه پیشتر بر ما جفا می‌نمود، الحال بشارت می‌دهد به همان ایمانی که قبل از این ویران می‌ساخت.»"},{"v":24,"t":"و خدا را در من تمجید نمودند."}],"en":[{"v":1,"t":"Paul, an apostle—not from men, nor through man, but through Jesus Christ, and God the Father, who raised him from the dead—"},{"v":2,"t":"and all the brothers who are with me, to the assemblies of Galatia:"},{"v":3,"t":"Grace to you and peace from God the Father and our Lord Jesus Christ,"},{"v":4,"t":"who gave himself for our sins, that he might deliver us out of this present evil age, according to the will of our God and Father—"},{"v":5,"t":"to whom be the glory forever and ever. Amen."},{"v":6,"t":"I marvel that you are so quickly deserting him who called you in the grace of Christ to a different “good news”,"},{"v":7,"t":"but there isn’t another “good news.” Only there are some who trouble you and want to pervert the Good News of Christ."},{"v":8,"t":"But even though we, or an angel from heaven, should preach to you any “good news” other than that which we preached to you, let him be cursed."},{"v":9,"t":"As we have said before, so I now say again: if any man preaches to you any “good news” other than that which you received, let him be cursed."},{"v":10,"t":"For am I now seeking the favor of men, or of God? Or am I striving to please men? For if I were still pleasing men, I wouldn’t be a servant of Christ."},{"v":11,"t":"But I make known to you, brothers, concerning the Good News which was preached by me, that it is not according to man."},{"v":12,"t":"For I didn’t receive it from man, nor was I taught it, but it came to me through revelation of Jesus Christ."},{"v":13,"t":"For you have heard of my way of living in time past in the Jews’ religion, how that beyond measure I persecuted the assembly of God and ravaged it."},{"v":14,"t":"I advanced in the Jews’ religion beyond many of my own age among my countrymen, being more exceedingly zealous for the traditions of my fathers."},{"v":15,"t":"But when it was the good pleasure of God, who separated me from my mother’s womb and called me through his grace,"},{"v":16,"t":"to reveal his Son in me, that I might preach him among the Gentiles, I didn’t immediately confer with flesh and blood,"},{"v":17,"t":"nor did I go up to Jerusalem to those who were apostles before me, but I went away into Arabia. Then I returned to Damascus."},{"v":18,"t":"Then after three years I went up to Jerusalem to visit Peter, and stayed with him fifteen days."},{"v":19,"t":"But of the other apostles I saw no one except James, the Lord’s brother."},{"v":20,"t":"Now about the things which I write to you, behold, before God, I’m not lying."},{"v":21,"t":"Then I came to the regions of Syria and Cilicia."},{"v":22,"t":"I was still unknown by face to the assemblies of Judea which were in Christ,"},{"v":23,"t":"but they only heard, “He who once persecuted us now preaches the faith that he once tried to destroy.”"},{"v":24,"t":"So they glorified God in me."}],"hr":[{"v":1,"t":"Pavao, apostol - ne od ljudi ni po kojem čovjeku, nego po Isusu Kristu i Bogu Ocu koji ga uskrisi od mrtvih -"},{"v":2,"t":"i sva braća koja su sa mnom: Crkvama u Galaciji."},{"v":3,"t":"Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista,"},{"v":4,"t":"koji sam sebe dade za grijehe naše da nas istrgne iz sadašnjega svijeta opakoga kao što je volja Boga i Oca našega,"},{"v":5,"t":"komu slava u vijeke vjekova! Amen."},{"v":6,"t":"Čudim se da od Onoga koji vas pozva na milost Kristovu tako brzo prelazite na neko drugo evanđelje,"},{"v":7,"t":"koje uostalom i ne postoji. Postoje samo neki koji vas zbunjuju i hoće prevratiti evanđelje Kristovo."},{"v":8,"t":"Ali kad bismo vam mi, ili kad bi vam anđeo s neba navješćivao neko evanđelje mimo onoga koje vam mi navijestismo, neka je proklet!"},{"v":9,"t":"Što smo već rekli, to sad i ponavljam: navješćuje li vam tko neko evanđelje mimo onoga koje primiste, neka je proklet."},{"v":10,"t":"Doista, nastojim li ovo pridobiti ljude ili Boga? Ili idem li za tim da ljudima ugodim? Kad bih sveudilj nastojao ljudima ugađati, ne bih bio Kristov sluga."},{"v":11,"t":"Obznanjujem vam, braćo: evanđelje koje sam navješćivao nije od ljudi,"},{"v":12,"t":"niti ga ja od kojeg čovjeka primih ili naučih, nego objavom Isusa Krista."},{"v":13,"t":"Ta čuli ste za moje negdašnje ponašanje u židovstvu: preko svake sam mjere progonio i pustošio Crkvu Božju"},{"v":14,"t":"te sam u židovstvu, prerevno odan otačkim predajama, nadmašio mnoge vršnjake u svojem narodu."},{"v":15,"t":"Ali kad se Onomu koji me odvoji već od majčine utrobe i pozva milošću svojom, svidjelo"},{"v":16,"t":"otkriti mi Sina svoga da ga navješćujem među poganima, odmah, ne posavjetovah se s tijelom i krvlju"},{"v":17,"t":"i ne uziđoh u Jeruzalem k onima koji bijahu apostoli prije mene, nego odoh u Arabiju pa se opet vratih u Damask."},{"v":18,"t":"Onda nakon tri godine uziđoh u Jeruzalem potražiti Kefu i ostadoh kod njega petnaest dana."},{"v":19,"t":"Od apostola ne vidjeh nikoga drugog osim Jakova, brata Gospodinova."},{"v":20,"t":"Što vam pišem, Bog mi je svjedok, ne lažem."},{"v":21,"t":"Zatim dođoh u krajeve sirijske i cilicijske."},{"v":22,"t":"Osobno pak bijah nepoznat Kristovim crkvama u Judeji."},{"v":23,"t":"One su samo čule: “Negdašnji naš progonitelj sada navješćuje vjeru koju je nekoć pustošio”"},{"v":24,"t":"i slavile su Boga zbog mene."}]},"2":{"fa":[{"v":1,"t":"پس بعد از چهارده سال با برنابا باز به اورشلیم رفتم و تیطس را همراه خود بردم."},{"v":2,"t":"ولی به الهام رفتم و انجیلی را که در میان امت هابدان موعظه می‌کنم، به ایشان عرضه داشتم، امادر خلوت به معتبرین، مبادا عبث بدوم یا دویده باشم."},{"v":3,"t":"لیکن تیطس نیز که همراه من و یونانی بود، مجبور نشد که مختون شود."},{"v":4,"t":"و این به‌سبب برادران کذبه بود که ایشان را خفیه درآوردند وخفیه درآمدند تا آزادی ما را که در مسیح عیسی داریم، جاسوسی کنند و تا ما را به بندگی درآوردند."},{"v":5,"t":"که ایشان را یک ساعت هم به اطاعت در این امر تابع نشدیم تا راستی انجیل در شماثابت ماند."},{"v":6,"t":"اما از آنانی که معتبراند که چیزی می‌باشند -هرچه بودند مرا تفاوتی نیست، خدا بر صورت انسان نگاه نمی کند - زیرا آنانی که معتبراند، به من هیچ نفع نرسانیدند."},{"v":7,"t":"بلکه به خلاف آن، چون دیدند که بشارت نامختونان به من سپرده شد، چنانکه بشارت مختونان به پطرس،"},{"v":8,"t":"زیرا او که برای رسالت مختونان در پطرس عمل کرد، در من هم برای امت‌ها عمل کرد."},{"v":9,"t":"پس چون یعقوب وکیفا و یوحنا که معتبر به ارکان بودند، آن فیضی را که به من عطا شده بود دیدند، دست رفاقت به من وبرنابا دادند تا ما به سوی امت‌ها برویم، چنانکه ایشان به سوی مختونان؛"},{"v":10,"t":"جز آنکه فقرا را یادبداریم و خود نیز غیور به کردن این کار بودم."},{"v":11,"t":"اما چون پطرس به انطاکیه آمد، او را روبرومخالفت نمودم زیرا که مستوجب ملامت بود،"},{"v":12,"t":"چونکه قبل از آمدن بعضی از جانب یعقوب، باامت‌ها غذا می‌خورد؛ ولی چون آمدند، از آنانی که اهل ختنه بودند ترسیده، باز ایستاد و خویشتن را جدا ساخت."},{"v":13,"t":"و سایر یهودیان هم با وی نفاق کردند، بحدی که برنابا نیز در نفاق ایشان گرفتارشد."},{"v":14,"t":"ولی چون دیدم که به راستی انجیل به استقامت رفتار نمی کنند، پیش روی همه پطرس را گفتم: «اگر تو که یهود هستی، به طریق امت‌ها ونه به طریق یهود زیست می‌کنی، چون است که امت‌ها را مجبور می‌سازی که به طریق یهود رفتارکنند؟»"},{"v":15,"t":"ما که طبع یهود هستیم و نه گناهکاران از امت‌ها،"},{"v":16,"t":"اما چونکه یافتیم که هیچ‌کس ازاعمال شریعت عادل شمرده نمی شود، بلکه به ایمان به عیسی مسیح، ما هم به مسیح عیسی ایمان آوردیم تا از ایمان به مسیح و نه از اعمال شریعت عادل شمرده شویم، زیرا که از اعمال شریعت هیچ بشری عادل شمرده نخواهد شد."},{"v":17,"t":"اما اگر چون عدالت در مسیح را می‌طلبم، خود هم گناهکار یافت شویم، آیا مسیح خادم گناه است؟ حاشا!"},{"v":18,"t":"زیرا اگر باز بنا کنم آنچه راکه خراب ساختم، هرآینه ثابت می‌کنم که خود متعدی هستم."},{"v":19,"t":"زانرو که من بواسطه شریعت نسبت به شریعت مردم تا نسبت به خدا زیست کنم."},{"v":20,"t":"با مسیح مصلوب شده‌ام ولی زندگی می‌کنم لیکن نه من بعد از این، بلکه مسیح در من زندگی می‌کند. و زندگانی که الحال در جسم می‌کنم، به ایمان بر پسر خدا می‌کنم که مرا محبت نمود و خود را برای من داد."},{"v":21,"t":"فیض خدا را باطل نمی سازم، زیرا اگر عدالت به شریعت می‌بود، هرآینه مسیح عبث مرد."}],"en":[{"v":1,"t":"Then after a period of fourteen years I went up again to Jerusalem with Barnabas, taking Titus also with me."},{"v":2,"t":"I went up by revelation, and I laid before them the Good News which I preach among the Gentiles, but privately before those who were respected, for fear that I might be running, or had run, in vain."},{"v":3,"t":"But not even Titus, who was with me, being a Greek, was compelled to be circumcised."},{"v":4,"t":"This was because of the false brothers secretly brought in, who stole in to spy out our liberty which we have in Christ Jesus, that they might bring us into bondage,"},{"v":5,"t":"to whom we gave no place in the way of subjection, not for an hour, that the truth of the Good News might continue with you."},{"v":6,"t":"But from those who were reputed to be important—whatever they were, it makes no difference to me; God doesn’t show partiality to man—they, I say, who were respected imparted nothing to me,"},{"v":7,"t":"but to the contrary, when they saw that I had been entrusted with the Good News for the uncircumcised, even as Peter with the Good News for the circumcised—"},{"v":8,"t":"for he who worked through Peter in the apostleship with the circumcised also worked through me with the Gentiles—"},{"v":9,"t":"and when they perceived the grace that was given to me, James and Cephas and John, those who were reputed to be pillars, gave to Barnabas and me the right hand of fellowship, that we should go to the Gentiles, and they to the circumcision."},{"v":10,"t":"They only asked us to remember the poor—which very thing I was also zealous to do."},{"v":11,"t":"But when Peter came to Antioch, I resisted him to his face, because he stood condemned."},{"v":12,"t":"For before some people came from James, he ate with the Gentiles. But when they came, he drew back and separated himself, fearing those who were of the circumcision."},{"v":13,"t":"And the rest of the Jews joined him in his hypocrisy, so that even Barnabas was carried away with their hypocrisy."},{"v":14,"t":"But when I saw that they didn’t walk uprightly according to the truth of the Good News, I said to Peter before them all, “If you, being a Jew, live as the Gentiles do, and not as the Jews do, why do you compel the Gentiles to live as the Jews do?"},{"v":15,"t":"“We, being Jews by nature and not Gentile sinners,"},{"v":16,"t":"yet knowing that a man is not justified by the works of the law but through faith in Jesus Christ, even we believed in Christ Jesus, that we might be justified by faith in Christ and not by the works of the law, because no flesh will be justified by the works of the law."},{"v":17,"t":"But if while we sought to be justified in Christ, we ourselves also were found sinners, is Christ a servant of sin? Certainly not!"},{"v":18,"t":"For if I build up again those things which I destroyed, I prove myself a law-breaker."},{"v":19,"t":"For I through the law died to the law, that I might live to God."},{"v":20,"t":"I have been crucified with Christ, and it is no longer I who live, but Christ lives in me. That life which I now live in the flesh, I live by faith in the Son of God, who loved me and gave himself up for me."},{"v":21,"t":"I don’t reject the grace of God. For if righteousness is through the law, then Christ died for nothing!”"}],"hr":[{"v":1,"t":"Zatim nakon četrnaest godina opet uziđoh u Jeruzalem s Barnabom, a povedoh sa sobom i Tita."},{"v":2,"t":"Uziđoh po objavi i izložih im - napose uglednijima - evanđelje koje propovijedam među poganima da ne bih možda, ili da nisam, trčao uzalud."},{"v":3,"t":"Čak ni Tit, pratilac moj, premda Grk, nije bio prisiljen obrezati se,"},{"v":4,"t":"i to radi uljeza, lažne braće, koja se ušuljaše da vrebaju slobodu koju imamo u Kristu Isusu, ne bi li nas učinili robovima."},{"v":5,"t":"Ne, ni načas im nismo popustili, nismo se podložili: da istina evanđelja ostane kod vas!"},{"v":6,"t":"A oni koji štogod znače - bili oni što bili, nije mi do toga, Bog ne gleda tko je tko - ti uglednici, uistinu, ništa nisu pridometnuli."},{"v":7,"t":"Nego naprotiv, vidjevši da mi je povjereno evanđelje za neobrezane, kao Petru za obrezane -"},{"v":8,"t":"jer Onaj koji je bio na djelu po Petrovu apostolstvu među obrezanima, bio je na djelu i po meni među poganima -"},{"v":9,"t":"i spoznavši milost koja mi je dana, Jakov, Kefa i Ivan, smatrani stupovima, pružiše meni i Barnabi desnice zajedništva: mi ćemo među pogane, a oni među obrezane!"},{"v":10,"t":"Samo neka se sjećamo siromaha, što sam revno i činio."},{"v":11,"t":"A kad Kefa stiže u Antiohiju, u lice mu se usprotivih jer je zavrijedio osudu:"},{"v":12,"t":"doista, prije nego stigoše neki od Jakova, blagovao je zajedno s poganima; a kad oni dođoše, počeo se povlačiti i odvajati bojeći se onih iz obrezanja."},{"v":13,"t":"Za njim se povedoše i ostali Židovi te je i Barnaba zaveden tom prijetvornošću."},{"v":14,"t":"Ali kad vidjeh da ne hode ravno, po istini evanđelja, rekoh Kefi pred svima: “Ako ti, Židov, poganski živiš, a ne židovski, kako možeš siliti pogane da se požidove?”"},{"v":15,"t":"Mi smo podrijetlom Židovi, a ne “grešnici iz poganstva”."},{"v":16,"t":"Ali znamo: čovjek se ne opravdava po djelima Zakona, nego vjerom u Isusa Krista. Zato i mi u Krista Isusa povjerovasmo da se opravdamo po vjeri u Krista, a ne po djelima Zakona jer se po djelima Zakona nitko neće opravdati."},{"v":17,"t":"Ako se pak po tome što zaiskasmo opravdati se u Kristu očitovalo da smo i mi grešnici, nije li onda Krist u službi grijeha? Nipošto!"},{"v":18,"t":"Doista, ako ponovno gradim što sam bio srušio, pokazujem da sam prijestupnik."},{"v":19,"t":"Ta po Zakonu ja Zakonu umrijeh da Bogu živim. S Kristom sam razapet."},{"v":20,"t":"Živim, ali ne više ja, nego živi u meni Krist. A što sada živim u tijelu, u vjeri živim u Sina Božjega koji me ljubio i predao samoga sebe za mene."},{"v":21,"t":"Ne dokidam milosti Božje! Doista, ako je opravdanje po Zakonu, onda je Krist uzalud umro."}]},"3":{"fa":[{"v":1,"t":"ای غلاطیان بی‌فهم، کیست که شما راافسون کرد تا راستی را اطاعت نکنید که پیش چشمان شما عیسی مسیح مصلوب شده مبین گردید؟"},{"v":2,"t":"فقط این را می‌خواهم از شمابفهمم که روح را از اعمال شریعت یافته‌اید یا ازخبر ایمان؟"},{"v":3,"t":"آیا اینقدر بی‌فهم هستید که به روح شروع کرده، الان به جسم کامل می‌شوید؟"},{"v":4,"t":"آیااینقدر زحمات را عبث کشیدید اگر فی الحقیقه عبث باشد؟"},{"v":5,"t":"پس آنکه روح را به شما عطامی کند و قوات در میان شما به ظهور می‌آورد، آیااز اعمال شریعت یا از خبر ایمان می‌کند؟"},{"v":6,"t":"چنانکه ابراهیم به خدا ایمان آورد و برای اوعدالت محسوب شد."},{"v":7,"t":"پس آگاهید که اهل ایمان فرزندان ابراهیم هستند."},{"v":8,"t":"و کتاب چون پیش دیدکه خدا امت‌ها را از ایمان عادل خواهد شمرد به ابراهیم بشارت داد که «جمیع امت‌ها از تو برکت خواهند یافت.»"},{"v":9,"t":"بنابراین اهل ایمان با ابراهیم ایمان دار برکت می‌یابند."},{"v":10,"t":"زیرا جمیع آنانی که از اعمال شریعت هستند، زیر لعنت می‌باشند زیرا مکتوب است: «ملعون است هر‌که ثابت نماند در تمام نوشته های کتاب شریعت تا آنها را به‌جا آرد.»"},{"v":11,"t":"اما واضح است که هیچ‌کس در حضور خدا ازشریعت عادل شمرده نمی شود، زیرا که «عادل به ایمان زیست خواهد نمود.»"},{"v":12,"t":"اما شریعت ازایمان نیست بلکه «آنکه به آنها عمل می‌کند، درآنها زیست خواهد نمود.»"},{"v":13,"t":"مسیح، ما را ازلعنت شریعت فدا کرد چونکه در راه ما لعنت شد، چنانکه مکتوب است «ملعون است هرکه بر دارآویخته شود.»"},{"v":14,"t":"تا برکت ابراهیم در مسیح عیسی بر امت‌ها آید و تا وعده روح را به وسیله ایمان حاصل کنیم."},{"v":15,"t":"‌ای برادران، به طریق انسان سخن می‌گویم، زیرا عهدی را که از انسان نیز استوار می‌شود، هیچ‌کس باطل نمی سازد و نمی افزاید."},{"v":16,"t":"اماوعده‌ها به ابراهیم و به نسل او گفته شد ونمی گوید «به نسلها» که گویا درباره بسیاری باشد، بلکه درباره یکی و «به نسل تو» که مسیح است."},{"v":17,"t":"و مقصود این است عهدی را که از خدا به مسیح بسته شده بود، شریعتی که چهارصد و سی سال بعد از آن نازل شد، باطل نمی سازد بطوری که وعده نیست شود."},{"v":18,"t":"زیرا اگر میراث از شریعت بودی، دیگر از وعده نبودی. لیکن خدا آن را به ابراهیم از وعده داد."},{"v":19,"t":"پس شریعت چیست؟ برای تقصیرها بر آن افزوده شد تا هنگام آمدن آن نسلی که وعده بدوداده شد و بوسیله فرشتگان به‌دست متوسطی مرتب گردید."},{"v":20,"t":"اما متوسط از یک نیست، اماخدا یک است."},{"v":21,"t":"پس آیا شریعت به خلاف وعده های خداست؟ حاشا! زیرا اگر شریعتی داده می‌شد که تواند حیات‌بخشد، هرآینه عدالت از شریعت حاصل می‌شد."},{"v":22,"t":"بلکه کتاب همه‌چیز را زیر گناه بست تا وعده‌ای که از ایمان به عیسی مسیح است، ایمانداران را عطا شود."},{"v":23,"t":"اما قبل از آمدن ایمان، زیر شریعت نگاه داشته بودیم و برای آن ایمانی که می‌بایست مکشوف شود، بسته شده بودیم."},{"v":24,"t":"پس شریعت لالای ماشد تا به مسیح برساند تا از ایمان عادل شمرده شویم."},{"v":25,"t":"لیکن چون ایمان آمد، دیگر زیر دست لالا نیستیم."},{"v":26,"t":"زیرا همگی شما بوسیله ایمان در مسیح عیسی، پسران خدا می‌باشید."},{"v":27,"t":"زیرا همه شما که در مسیح تعمید یافتید، مسیح را در بر‌گرفتید."},{"v":28,"t":"هیچ ممکن نیست که یهود باشد یا یونانی و نه غلام و نه آزاد و نه مرد و نه زن، زیرا که همه شمادر مسیح عیسی یک می‌باشید."},{"v":29,"t":"اما اگر شما ازآن مسیح می‌باشید، هرآینه نسل ابراهیم وبرحسب وعده، وارث هستید."}],"en":[{"v":1,"t":"Foolish Galatians, who has bewitched you not to obey the truth, before whose eyes Jesus Christ was openly portrayed among you as crucified?"},{"v":2,"t":"I just want to learn this from you: Did you receive the Spirit by the works of the law, or by hearing of faith?"},{"v":3,"t":"Are you so foolish? Having begun in the Spirit, are you now completed in the flesh?"},{"v":4,"t":"Did you suffer so many things in vain, if it is indeed in vain?"},{"v":5,"t":"He therefore who supplies the Spirit to you and does miracles among you, does he do it by the works of the law, or by hearing of faith?"},{"v":6,"t":"Even so, Abraham “believed God, and it was counted to him for righteousness.”"},{"v":7,"t":"Know therefore that those who are of faith are children of Abraham."},{"v":8,"t":"The Scripture, foreseeing that God would justify the Gentiles by faith, preached the Good News beforehand to Abraham, saying, “In you all the nations will be blessed.”"},{"v":9,"t":"So then, those who are of faith are blessed with the faithful Abraham."},{"v":10,"t":"For as many as are of the works of the law are under a curse. For it is written, “Cursed is everyone who doesn’t continue in all things that are written in the book of the law, to do them.”"},{"v":11,"t":"Now that no man is justified by the law before God is evident, for, “The righteous will live by faith.”"},{"v":12,"t":"The law is not of faith, but, “The man who does them will live by them.”"},{"v":13,"t":"Christ redeemed us from the curse of the law, having become a curse for us. For it is written, “Cursed is everyone who hangs on a tree,”"},{"v":14,"t":"that the blessing of Abraham might come on the Gentiles through Christ Jesus, that we might receive the promise of the Spirit through faith."},{"v":15,"t":"Brothers, speaking of human terms, though it is only a man’s covenant, yet when it has been confirmed, no one makes it void or adds to it."},{"v":16,"t":"Now the promises were spoken to Abraham and to his offspring. He doesn’t say, “To descendants”, as of many, but as of one, “To your offspring”, which is Christ."},{"v":17,"t":"Now I say this: A covenant confirmed beforehand by God in Christ, the law, which came four hundred thirty years after, does not annul, so as to make the promise of no effect."},{"v":18,"t":"For if the inheritance is of the law, it is no more of promise; but God has granted it to Abraham by promise."},{"v":19,"t":"Then why is there the law? It was added because of transgressions, until the offspring should come to whom the promise has been made. It was ordained through angels by the hand of a mediator."},{"v":20,"t":"Now a mediator is not between one, but God is one."},{"v":21,"t":"Is the law then against the promises of God? Certainly not! For if there had been a law given which could make alive, most certainly righteousness would have been of the law."},{"v":22,"t":"But the Scripture imprisoned all things under sin, that the promise by faith in Jesus Christ might be given to those who believe."},{"v":23,"t":"But before faith came, we were kept in custody under the law, confined for the faith which should afterwards be revealed."},{"v":24,"t":"So that the law has become our tutor to bring us to Christ, that we might be justified by faith."},{"v":25,"t":"But now that faith has come, we are no longer under a tutor."},{"v":26,"t":"For you are all children of God, through faith in Christ Jesus."},{"v":27,"t":"For as many of you as were baptized into Christ have put on Christ."},{"v":28,"t":"There is neither Jew nor Greek, there is neither slave nor free man, there is neither male nor female; for you are all one in Christ Jesus."},{"v":29,"t":"If you are Christ’s, then you are Abraham’s offspring and heirs according to promise."}],"hr":[{"v":1,"t":"O bezumni Galaćani, tko li vas opčara? A pred očima vam je Isus Krist bio ocrtan kao Raspeti."},{"v":2,"t":"Ovo bih samo htio doznati od vas: jeste li primili Duha po djelima Zakona ili po vjeri u Poruku?"},{"v":3,"t":"Tako li ste bezumni? Započeli ste u Duhu pa da sada u tijelu dovršite?"},{"v":4,"t":"Zar ste toliko toga uzalud doživjeli? A kad bi doista bilo uzalud!"},{"v":5,"t":"Onaj dakle koji vam daje Duha i čini među vama silna djela, čini li to zbog djela Zakona ili zbog vjere u Poruku?"},{"v":6,"t":"Tako Abraham povjerova Bogu i uračuna mu se u pravednost."},{"v":7,"t":"Shvatite dakle: oni od vjere, to su sinovi Abrahamovi."},{"v":8,"t":"A Pismo, predvidjevši da Bog po vjeri opravdava pogane, unaprijed navijesti Abrahamu: U tebi će blagoslovljeni biti svi narodi."},{"v":9,"t":"Tako: oni od vjere blagoslivlju se s vjernikom Abrahamom."},{"v":10,"t":"Doista, koji su god od djela Zakona, pod prokletstvom su. Ta pisano je: Proklet tko se god ne drži i tko ne vrši svega što je napisano u Knjizi Zakona."},{"v":11,"t":"A da se pred Bogom nitko ne opravdava Zakonom, očito je jer: Pravednik će od vjere živjeti."},{"v":12,"t":"Zakon pak nije od vjere, nego veli: Tko ga vrši, u njemu će naći život."},{"v":13,"t":"Krist nas otkupi od prokletstva Zakona, postavši za nas prokletstvom - jer pisano je: Proklet je tko god visi na drvetu -"},{"v":14,"t":"da u Kristu Isusu na pogane dođe blagoslov Abrahamov: da Obećanje, Duha, primimo po vjeri."},{"v":15,"t":"Braćo, po ljudsku govorim: već i ljudski valjan savez nitko ne poništava niti mu što dodaje."},{"v":16,"t":"A ova su obećanja dana Abrahamu i potomstvu njegovu. Ne veli se: “i potomcima” kao o mnogima, nego kao o jednomu: I potomstvu tvojem, to jest Kristu."},{"v":17,"t":"Ovo hoću kazati: Saveza koji je Bog valjano sklopio ne obeskrepljuje Zakon, koji je nastao četiri stotine i trideset godina poslije, i ne dokida obećanja."},{"v":18,"t":"Doista, ako se baština zadobiva po Zakonu, ne zadobiva se po obećanju. A Abrahama je Bog po obećanju obdario."},{"v":19,"t":"Čemu onda Zakon? Dometnut je poradi prekršaja dok ne dođe potomstvo komu je namijenjeno obećanje; sastavljen je po anđelima preko posrednika."},{"v":20,"t":"Posrednika pak nema gdje je samo jedan. A Bog je jedan."},{"v":21,"t":"Zar je dakle Zakon protiv obećanja Božjih? Nipošto! Jer da je dan Zakon koji bi mogao oživljavati, pravednost bi doista proizlazila iz Zakona."},{"v":22,"t":"Ali je Pismo sve zatvorilo pod grijeh da se, po vjeri u Isusa Krista, obećano dade onima koji vjeruju."},{"v":23,"t":"Prije dolaska vjere, pod Zakonom zatvoreni, bili smo čuvani za vjeru koja se imala objaviti."},{"v":24,"t":"Tako nam je Zakon bio nadzirateljem sve do Krista da se po vjeri opravdamo."},{"v":25,"t":"A otkako je nadošla vjera, nismo više pod nadzirateljem."},{"v":26,"t":"Uistinu, svi ste sinovi Božji, po vjeri u Kristu Isusu."},{"v":27,"t":"Doista, koji ste god u Krista kršteni, Kristom se zaodjenuste."},{"v":28,"t":"Nema više: Židov - Grk! Nema više: rob - slobodnjak! Nema više: muško - žensko! Svi ste vi Jedan u Kristu Isusu!"},{"v":29,"t":"Ako li ste Kristovi, onda ste Abrahamovo potomstvo, baštinici po obećanju."}]},"4":{"fa":[{"v":1,"t":"است، از غلام هیچ فرق ندارد، هرچندمالک همه باشد."},{"v":2,"t":"بلکه زیردست ناظران و وکلامی باشد تا روزی که پدرش تعیین کرده باشد."},{"v":3,"t":"همچنین ما نیز چون صغیر می‌بودیم، زیر اصول دنیوی غلام می‌بودیم."},{"v":4,"t":"لیکن چون زمان به‌کمال رسید، خدا پسر خود را فرستاد که از زن زاییده شد و زیر شریعت متولد،"},{"v":5,"t":"تا آنانی را که زیرشریعت باشند فدیه کند تا آنکه پسرخواندگی رابیابیم."},{"v":6,"t":"اما چونکه پسر هستید، خدا روح پسرخود را در دلهای شما فرستاد که ندا می‌کند «یاابا» یعنی «ای پدر.»"},{"v":7,"t":"لهذا دیگر غلام نیستی بلکه پسر، و چون پسر هستی، وارث خدا نیز بوسیله مسیح."},{"v":8,"t":"لیکن در آن زمان چون خدا را نمی شناختید، آنانی را که طبیعت خدایان نبودند، بندگی می‌کردید."},{"v":9,"t":"اما الحال که خدا را می‌شناسید بلکه خدا شما را می‌شناسد، چگونه باز می‌گردید به سوی آن اصول ضعیف و فقیر که دیگرمی خواهید از سر نو آنها را بندگی کنید؟"},{"v":10,"t":"روزهاو ماهها و فصل‌ها و سالها را نگاه می‌دارید."},{"v":11,"t":"درباره شما ترس دارم که مبادا برای شما عبث زحمت کشیده باشم."},{"v":12,"t":"‌ای برادران، از شما استدعا دارم که مثل من بشوید، چنانکه من هم مثل شما شده‌ام. به من هیچ ظلم نکردید."},{"v":13,"t":"اما آگاهید که به‌سبب ضعف بدنی، اول به شما بشارت دادم."},{"v":14,"t":"و آن امتحان مرا که در جسم من بود، خوار نشمردید و مکروه نداشتید، بلکه مرا چون فرشته خدا و مثل مسیح عیسی پذیرفتید."},{"v":15,"t":"پس کجا است آن مبارک بادی شما؟ زیرا به شما شاهدم که اگرممکن بودی، چشمان خود را بیرون آورده، به من می‌دادید."},{"v":16,"t":"پس چون به شما راست می‌گویم، آیا دشمن شما شده‌ام؟"},{"v":17,"t":"شما را به غیرت می‌طلبند، لیکن نه به خیر، بلکه می‌خواهند در را بر روی شما ببندند تا شما ایشان را بغیرت بطلبید."},{"v":18,"t":"لیکن غیرت در امر نیکو در هر زمان نیکو است، نه‌تنها چون من نزد شما حاضر باشم."},{"v":19,"t":"‌ای فرزندان من که برای شما باز درد زه دارم تاصورت مسیح در شما بسته شود."},{"v":20,"t":"باری خواهش می‌کردم که الان نزد شما حاضر می‌بودم تا سخن خود را تبدیل کنم، زیرا که درباره شمامتحیر شده‌ام."},{"v":21,"t":"شما که می‌خواهید زیر شریعت باشید، مرابگویید آیا شریعت را نمی شنوید؟"},{"v":22,"t":"زیرامکتوب است ابراهیم را دو پسر بود، یکی از کنیزو دیگری از آزاد."},{"v":23,"t":"لیکن پسر کنیز، بحسب جسم تولد یافت و پسر آزاد، برحسب وعده."},{"v":24,"t":"واین امور بطور مثل گفته شد زیرا که این دو زن، دوعهد می‌باشند، یکی از کوه سینا برای بندگی می‌زاید و آن هاجر است."},{"v":25,"t":"زیرا که هاجر کوه سینا است در عرب، و مطابق است با اورشلیمی که موجود است، زیرا که با فرزندانش در بندگی می‌باشد."},{"v":26,"t":"لیکن اورشلیم بالا آزاد است که مادرجمیع ما می‌باشد."},{"v":27,"t":"زیرا مکتوب است: «ای نازاد که نزاییده‌ای، شاد باش! صدا کن و فریادبرآور‌ای تو که درد زه ندیده‌ای، زیرا که فرزندان زن بی‌کس از اولاد شوهردار بیشتراند.»"},{"v":28,"t":"لیکن ما‌ای برادران، چون اسحاق فرزندان وعده می‌باشیم."},{"v":29,"t":"بلکه چنانکه آنوقت آنکه برحسب جسم تولد یافت، بر وی که برحسب روح بود جفامی کرد، همچنین الان نیز هست."},{"v":30,"t":"لیکن کتاب چه می‌گوید؟ «کنیز و پسر او را بیرون کن زیرا پسرکنیز با پسر آزاد میراث نخواهد یافت.»"},{"v":31,"t":"خلاصه‌ای برادران، فرزندان کنیز نیستیم بلکه از زن آزادیم."}],"en":[{"v":1,"t":"But I say that so long as the heir is a child, he is no different from a bondservant, though he is lord of all,"},{"v":2,"t":"but is under guardians and stewards until the day appointed by the father."},{"v":3,"t":"So we also, when we were children, were held in bondage under the elemental principles of the world."},{"v":4,"t":"But when the fullness of the time came, God sent out his Son, born to a woman, born under the law,"},{"v":5,"t":"that he might redeem those who were under the law, that we might receive the adoption as children."},{"v":6,"t":"And because you are children, God sent out the Spirit of his Son into your hearts, crying, “Abba, Father!”"},{"v":7,"t":"So you are no longer a bondservant, but a son; and if a son, then an heir of God through Christ."},{"v":8,"t":"However at that time, not knowing God, you were in bondage to those who by nature are not gods."},{"v":9,"t":"But now that you have come to know God, or rather to be known by God, why do you turn back again to the weak and miserable elemental principles, to which you desire to be in bondage all over again?"},{"v":10,"t":"You observe days, months, seasons, and years."},{"v":11,"t":"I am afraid for you, that I might have wasted my labor for you."},{"v":12,"t":"I beg you, brothers, become as I am, for I also have become as you are. You did me no wrong,"},{"v":13,"t":"but you know that because of weakness in the flesh I preached the Good News to you the first time."},{"v":14,"t":"That which was a temptation to you in my flesh, you didn’t despise nor reject; but you received me as an angel of God, even as Christ Jesus."},{"v":15,"t":"What was the blessing you enjoyed? For I testify to you that, if possible, you would have plucked out your eyes and given them to me."},{"v":16,"t":"So then, have I become your enemy by telling you the truth?"},{"v":17,"t":"They zealously seek you in no good way. No, they desire to alienate you, that you may seek them."},{"v":18,"t":"But it is always good to be zealous in a good cause, and not only when I am present with you."},{"v":19,"t":"My little children, of whom I am again in travail until Christ is formed in you—"},{"v":20,"t":"but I could wish to be present with you now, and to change my tone, for I am perplexed about you."},{"v":21,"t":"Tell me, you that desire to be under the law, don’t you listen to the law?"},{"v":22,"t":"For it is written that Abraham had two sons, one by the servant, and one by the free woman."},{"v":23,"t":"However, the son by the servant was born according to the flesh, but the son by the free woman was born through promise."},{"v":24,"t":"These things contain an allegory, for these are two covenants. One is from Mount Sinai, bearing children to bondage, which is Hagar."},{"v":25,"t":"For this Hagar is Mount Sinai in Arabia, and answers to the Jerusalem that exists now, for she is in bondage with her children."},{"v":26,"t":"But the Jerusalem that is above is free, which is the mother of us all."},{"v":27,"t":"For it is written, “Rejoice, you barren who don’t bear. Break out and shout, you who don’t travail. For the desolate women have more children than her who has a husband.”"},{"v":28,"t":"Now we, brothers, as Isaac was, are children of promise."},{"v":29,"t":"But as then, he who was born according to the flesh persecuted him who was born according to the Spirit, so also it is now."},{"v":30,"t":"However, what does the Scripture say? “Throw out the servant and her son, for the son of the servant will not inherit with the son of the free woman.”"},{"v":31,"t":"So then, brothers, we are not children of a servant, but of the free woman."}],"hr":[{"v":1,"t":"Hoću reći: sve dok je baštinik maloljetan, ništa se ne razlikuje od roba premda je gospodar svega:"},{"v":2,"t":"pod skrbnicima je i upraviteljima sve do dana koji je odredio otac."},{"v":3,"t":"Tako i mi: dok bijasmo maloljetni, robovasmo počelima svijeta."},{"v":4,"t":"A kada dođe punina vremena, odasla Bog Sina svoga: od žene bi rođen, Zakonu podložan"},{"v":5,"t":"da podložnike Zakona otkupi te primimo posinstvo."},{"v":6,"t":"A budući da ste sinovi, odasla Bog u srca vaša Duha Sina svoga koji kliče: “Abba! Oče!”"},{"v":7,"t":"Tako više nisi rob nego sin; ako pak sin, onda i baštinik po Bogu."},{"v":8,"t":"Onda dok još niste poznavali Boga, služili ste bogovima koji po naravi to nisu."},{"v":9,"t":"Ali sada kad ste spoznali Boga - zapravo, kad je Bog spoznao vas - kako se sad opet vraćate k nemoćnim i bijednim počelima i opet im, ponovno, hoćete robovati?"},{"v":10,"t":"Dane pomno opslužujete, i mjesece, i vremena, i godine!"},{"v":11,"t":"Sve se bojim za vas! Da se možda nisam uzalud trudio oko vas!"},{"v":12,"t":"Postanite, braćo, molim vas, kao ja jer i ja postadoh kao vi. Ničim me niste povrijedili."},{"v":13,"t":"Znate: prvi sam vam put za bolesti navješćivao evanđelje."},{"v":14,"t":"Svoju kušnju, moje tijelo, niste ni prezreli ni odbacili, nego ste me primili kao anđela Božjega, kao Krista Isusa."},{"v":15,"t":"Gdje je sada ono vaše blaženstvo? Svjedočim vam doista: kad bi bilo moguće, oči biste svoje bili iskopali i dali mi ih."},{"v":16,"t":"Tako? Postadoh li vam neprijateljem propovijedajući vam istinu?"},{"v":17,"t":"Oni revnuju za vas, ne časno, nego - odvojiti vas hoće da onda vi za njih revnujete."},{"v":18,"t":"Dobro je da se za vas revnuje u dobru uvijek, a ne samo kad sam nazočan kod vas,"},{"v":19,"t":"dječice moja, koju ponovno u trudovima rađam dok se Krist ne oblikuje u vama."},{"v":20,"t":"Htio bih sada biti kod vas, pa i jezik promijeniti, jer ne znam što bih s vama."},{"v":21,"t":"Recite mi vi, koji želite biti pod Zakonom, zar ne čujete Zakona?"},{"v":22,"t":"Ta pisano je da je Abraham imao dva sina, jednoga od ropkinje i jednoga od slobodne."},{"v":23,"t":"Ali onaj od ropkinje rođen je po tijelu, a onaj od slobodne snagom obećanja."},{"v":24,"t":"To je slika. Doista, te žene dva su Saveza: jedan s brda Sinaja, koji rađa za ropstvo - to je Hagara."},{"v":25,"t":"Jer Hagara znači brdo Sinaj u Arabiji i odgovara sadašnjem Jeruzalemu jer robuje zajedno sa svojom djecom."},{"v":26,"t":"Onaj pak Jeruzalem gore slobodan je; on je majka naša."},{"v":27,"t":"Pisano je doista: Kliči, nerotkinjo, koja ne rađaš, podvikuj od radosti, ti što ne znaš za trudove! Jer osamljena više djece ima negoli udana."},{"v":28,"t":"Vi ste, braćo, kao Izak, djeca obećanja."},{"v":29,"t":"I kao što je onda onaj po tijelu rođeni progonio onoga po duhu rođenoga, tako je i sada."},{"v":30,"t":"Nego, što veli Pismo? Otjeraj sluškinju i sina njezina jer sin sluškinje ne smije biti baštinik sa sinom slobodne."},{"v":31,"t":"Zato, braćo, nismo djeca ropkinje nego slobodne."}]},"5":{"fa":[{"v":1,"t":"پس به آن آزادی که مسیح ما را به آن آزادکرد استوار باشید و باز در یوغ بندگی گرفتار مشوید."},{"v":2,"t":"اینک من پولس به شما می‌گویم که اگر مختون شوید، مسیح برای شما هیچ نفع ندارد."},{"v":3,"t":"بلی باز به هرکس که مختون شود شهادت می‌دهم که مدیون است که تمامی شریعت را به‌جا آورد."},{"v":4,"t":"همه شما که از شریعت عادل می‌شوید، از مسیح باطل و از فیض ساقطگشته‌اید."},{"v":5,"t":"زیرا که ما بواسطه روح از ایمان مترقب امید عدالت هستیم."},{"v":6,"t":"و در مسیح عیسی نه ختنه فایده دارد و نه نامختونی بلکه ایمانی که به محبت عمل می‌کند."},{"v":7,"t":"خوب می‌دویدید. پس کیست که شما را ازاطاعت راستی منحرف ساخته است؟"},{"v":8,"t":"این ترغیب از او که شما را خوانده است نیست."},{"v":9,"t":"خمیرمایه اندک تمام خمیر را مخمر می‌سازد."},{"v":10,"t":"من در خداوند بر شما اعتماد دارم که هیچ رای دیگر نخواهید داشت، لیکن آنکه شما رامضطرب سازد هرکه باشد قصاص خود راخواهد یافت."},{"v":11,"t":"اما‌ای برادران اگر من تا به حال به ختنه موعظه می‌کردم، چرا جفا می‌دیدم؟ زیراکه در این صورت لغزش صلیب برداشته می‌شد."},{"v":12,"t":"کاش آنانی که شما را مضطرب می‌سازند خویشتن را منقطع می‌ساختند."},{"v":13,"t":"زیرا که شما‌ای برادران به آزادی خوانده شده‌اید؛ اما زنهار آزادی خود را فرصت جسم مگردانید، بلکه به محبت، یکدیگر را خدمت کنید."},{"v":14,"t":"زیرا که تمامی شریعت در یک کلمه کامل می‌شود یعنی در اینکه همسایه خود راچون خویشتن محبت نما."},{"v":15,"t":"اما اگر همدیگر رابگزید و بخورید، باحذر باشید که مبادا ازیکدیگر هلاک شوید."},{"v":16,"t":"اما می‌گویم به روح رفتار کنید پس شهوات جسم را به‌جا نخواهید آورد."},{"v":17,"t":"زیرا خواهش جسم به خلاف روح است و خواهش روح به خلاف جسم و این دو با یکدیگر منازعه می‌کنندبطوری که آنچه می‌خواهید نمی کنید."},{"v":18,"t":"اما اگراز روح هدایت شدید، زیر شریعت نیستید."},{"v":19,"t":"و اعمال جسم آشکار است، یعنی زنا وفسق و ناپاکی و فجور،"},{"v":20,"t":"و بت‌پرستی وجادوگری و دشمنی و نزاع و کینه و خشم وتعصب و شقاق و بدعتها،"},{"v":21,"t":"و حسد و قتل ومستی و لهو و لعب و امثال اینها که شما را خبرمی دهم چنانکه قبل از این دادم، که کنندگان چنین کارها وارث ملکوت خدا نمی شوند."},{"v":22,"t":"لیکن ثمره روح، محبت و خوشی وسلامتی و حلم و مهربانی و نیکویی و ایمان وتواضع و پرهیزکاری است،"},{"v":23,"t":"که هیچ شریعت مانع چنین کارها نیست."},{"v":24,"t":"و آنانی که از آن مسیح می‌باشند، جسم را با هوسها و شهواتش مصلوب ساخته‌اند."},{"v":25,"t":"اگر به روح زیست کنیم، به روح هم رفتار بکنیم."},{"v":26,"t":"لاف‌زن مشویم تا یکدیگر را به خشم آوریم و بر یکدیگر حسد بریم."}],"en":[{"v":1,"t":"Stand firm therefore in the liberty by which Christ has made us free, and don’t be entangled again with a yoke of bondage."},{"v":2,"t":"Behold, I, Paul, tell you that if you receive circumcision, Christ will profit you nothing."},{"v":3,"t":"Yes, I testify again to every man who receives circumcision that he is a debtor to do the whole law."},{"v":4,"t":"You are alienated from Christ, you who desire to be justified by the law. You have fallen away from grace."},{"v":5,"t":"For we through the Spirit, by faith wait for the hope of righteousness."},{"v":6,"t":"For in Christ Jesus neither circumcision nor uncircumcision amounts to anything, but faith working through love."},{"v":7,"t":"You were running well! Who interfered with you that you should not obey the truth?"},{"v":8,"t":"This persuasion is not from him who calls you."},{"v":9,"t":"A little yeast grows through the whole lump."},{"v":10,"t":"I have confidence toward you in the Lord that you will think no other way. But he who troubles you will bear his judgment, whoever he is."},{"v":11,"t":"But I, brothers, if I still preach circumcision, why am I still persecuted? Then the stumbling block of the cross has been removed."},{"v":12,"t":"I wish that those who disturb you would cut themselves off."},{"v":13,"t":"For you, brothers, were called for freedom. Only don’t use your freedom as an opportunity for the flesh, but through love be servants to one another."},{"v":14,"t":"For the whole law is fulfilled in one word, in this: “You shall love your neighbor as yourself.”"},{"v":15,"t":"But if you bite and devour one another, be careful that you don’t consume one another."},{"v":16,"t":"But I say, walk by the Spirit, and you won’t fulfill the lust of the flesh."},{"v":17,"t":"For the flesh lusts against the Spirit, and the Spirit against the flesh; and these are contrary to one another, that you may not do the things that you desire."},{"v":18,"t":"But if you are led by the Spirit, you are not under the law."},{"v":19,"t":"Now the deeds of the flesh are obvious, which are: adultery, sexual immorality, uncleanness, lustfulness,"},{"v":20,"t":"idolatry, sorcery, hatred, strife, jealousies, outbursts of anger, rivalries, divisions, heresies,"},{"v":21,"t":"envy, murders, drunkenness, orgies, and things like these; of which I forewarn you, even as I also forewarned you, that those who practice such things will not inherit God’s Kingdom."},{"v":22,"t":"But the fruit of the Spirit is love, joy, peace, patience, kindness, goodness, faith,"},{"v":23,"t":"gentleness, and self-control. Against such things there is no law."},{"v":24,"t":"Those who belong to Christ have crucified the flesh with its passions and lusts."},{"v":25,"t":"If we live by the Spirit, let’s also walk by the Spirit."},{"v":26,"t":"Let’s not become conceited, provoking one another, and envying one another."}],"hr":[{"v":1,"t":"Za slobodu nas Krist oslobodi! Držite se dakle i ne dajte se ponovno u jaram ropstva!"},{"v":2,"t":"Evo ja, Pavao, velim vam: ako se obrežete, Krist vam ništa neće koristiti."},{"v":3,"t":"I ponovno jamčim svakom čovjeku koji se obreže: dužan je opsluživati sav Zakon."},{"v":4,"t":"Prekinuli ste s Kristom vi koji se u Zakonu mislite opravdati; iz milosti ste ispali."},{"v":5,"t":"Jer mi po Duhu iz vjere očekujemo pravednost, nadu svoju."},{"v":6,"t":"Uistinu, u Kristu Isusu ništa ne vrijedi ni obrezanje ni neobrezanje, nego - vjera ljubavlju djelotvorna."},{"v":7,"t":"Dobro ste trčali; tko li vas je samo spriječio da se više ne pokoravate istini?"},{"v":8,"t":"Ta pobuda nije od Onoga koji vas zove!"},{"v":9,"t":"Malo kvasca cijelo tijesto ukvasa."},{"v":10,"t":"Ja se uzdam u vas u Gospodinu: vi nećete drukčije misliti. A tko vas zbunjuje, snosit će osudu, tko god bio."},{"v":11,"t":"A ja, braćo, ako sveudilj propovijedam obrezanje, zašto me sveudilj progone? Onda je obeskrijepljena sablazan križa!"},{"v":12,"t":"Uškopili se oni koji vas podbunjuju!"},{"v":13,"t":"Doista vi ste, braćo, na slobodu pozvani! Samo neka ta sloboda ne bude izlikom tijelu, nego - ljubavlju služite jedni drugima."},{"v":14,"t":"Ta sav je Zakon ispunjen u jednoj jedinoj riječi, u ovoj: Ljubi bližnjega svoga kao sebe samoga!"},{"v":15,"t":"Ako li pak jedni druge grizete i glođete, pazite da jedni druge ne proždrete."},{"v":16,"t":"Hoću reći: po Duhu živite pa nećete ugađati požudi tijela!"},{"v":17,"t":"Jer tijelo žudi protiv Duha, a Duh protiv tijela. Doista, to se jedno drugomu protivi da ne činite što hoćete."},{"v":18,"t":"Ali ako vas Duh vodi, niste pod Zakonom."},{"v":19,"t":"A očita su djela tijela. To su: bludnost, nečistoća, razvratnost,"},{"v":20,"t":"idolopoklonstvo, vračanje, neprijateljstva, svađa, ljubomor, srdžbe, spletkarenja, razdori, strančarenja,"},{"v":21,"t":"zavisti, pijančevanja, pijanke i tome slično. Unaprijed vam kažem, kao što vam već rekoh: koji takvo što čine, kraljevstva Božjega neće baštiniti."},{"v":22,"t":"Plod je pak Duha: ljubav, radost, mir, velikodušnost, uslužnost, dobrota, vjernost,"},{"v":23,"t":"blagost, uzdržljivost. Protiv tih nema zakona."},{"v":24,"t":"Koji su Kristovi, razapeše tijelo sa strastima i požudama."},{"v":25,"t":"Ako živimo po Duhu, po Duhu se i ravnajmo!"},{"v":26,"t":"Ne hlepimo za taštom slavom! Ne izazivajmo jedni druge, ne zaviđajmo jedni drugima!"}]},"6":{"fa":[{"v":1,"t":"اما‌ای برادران، اگر کسی به خطایی گرفتارشود، شما که روحانی هستید چنین شخص را به روح تواضع اصلاح کنید. و خود راملاحظه کن که مبادا تو نیز در تجربه افتی."},{"v":2,"t":"بارهای سنگین یکدیگر را متحمل شوید و بدین نوع شریعت مسیح را به‌جا آرید."},{"v":3,"t":"زیرا اگر کسی خود را شخص گمان برد و حال آنکه چیزی نباشد، خود را می‌فریبد."},{"v":4,"t":"اما هرکس عمل خودرا امتحان بکند، آنگاه فخر در خود به تنهایی خواهد داشت نه در دیگری،"},{"v":5,"t":"زیرا هرکس حامل بار خود خواهد شد."},{"v":6,"t":"اما هرکه در کلام تعلیم یافته باشد، معلم خود را در همه‌چیزهای خوب مشارک بسازد."},{"v":7,"t":"خود را فریب مدهید، خدا رااستهزاء نمی توان کرد. زیرا که آنچه آدمی بکارد، همان را درو خواهد کرد."},{"v":8,"t":"زیرا هر‌که برای جسم خود کارد، از جسم فساد را درو کند و هرکه برای روح کارد از روح حیات جاودانی خواهد دروید."},{"v":9,"t":"لیکن از نیکوکاری خسته نشویم زیرا که درموسم آن درو خواهیم کرد اگر ملول نشویم."},{"v":10,"t":"خلاصه بقدری که فرصت داریم با جمیع مردم احسان بنماییم، علی الخصوص با اهل بیت ایمان."},{"v":11,"t":"ملاحظه کنید چه حروف جلی بدست خود به شما نوشتم."},{"v":12,"t":"آنانی که می‌خواهند صورتی نیکو در جسم نمایان سازند، ایشان شمارا مجبور می‌سازند که مختون شوید، محض اینکه برای صلیب مسیح جفا نبینند."},{"v":13,"t":"زیراایشان نیز که مختون می‌شوند، خود شریعت رانگاه نمی دارند بلکه می‌خواهند شما مختون شوید تا در جسم شما فخر کنند."},{"v":14,"t":"لیکن حاشا ازمن که فخر کنم جز از صلیب خداوند ما عیسی مسیح که بوسیله او دنیا برای من مصلوب شد و من برای دنیا."},{"v":15,"t":"زیرا که در مسیح عیسی نه ختنه چیزی است و نه نامختونی بلکه خلقت تازه."},{"v":16,"t":"وآنانی که بدین قانون رفتار می‌کنند، سلامتی ورحمت بر ایشان باد و بر اسرائیل خدا."},{"v":17,"t":"بعد ازاین هیچ‌کس مرا زحمت نرساند زیرا که من در بدن خود داغهای خداوند عیسی را دارم."},{"v":18,"t":"فیض خداوند ما عیسی مسیح با روح شما باد‌ای برادران. آمین."}],"en":[{"v":1,"t":"Brothers, even if a man is caught in some fault, you who are spiritual must restore such a one in a spirit of gentleness, looking to yourself so that you also aren’t tempted."},{"v":2,"t":"Bear one another’s burdens, and so fulfill the law of Christ."},{"v":3,"t":"For if a man thinks himself to be something when he is nothing, he deceives himself."},{"v":4,"t":"But let each man examine his own work, and then he will have reason to boast in himself, and not in someone else."},{"v":5,"t":"For each man will bear his own burden."},{"v":6,"t":"But let him who is taught in the word share all good things with him who teaches."},{"v":7,"t":"Don’t be deceived. God is not mocked, for whatever a man sows, that he will also reap."},{"v":8,"t":"For he who sows to his own flesh will from the flesh reap corruption. But he who sows to the Spirit will from the Spirit reap eternal life."},{"v":9,"t":"Let’s not be weary in doing good, for we will reap in due season if we don’t give up."},{"v":10,"t":"So then, as we have opportunity, let’s do what is good toward all men, and especially toward those who are of the household of the faith."},{"v":11,"t":"See with what large letters I write to you with my own hand."},{"v":12,"t":"As many as desire to make a good impression in the flesh compel you to be circumcised, just so they may not be persecuted for the cross of Christ."},{"v":13,"t":"For even they who receive circumcision don’t keep the law themselves, but they desire to have you circumcised, so that they may boast in your flesh."},{"v":14,"t":"But far be it from me to boast except in the cross of our Lord Jesus Christ, through which the world has been crucified to me, and I to the world."},{"v":15,"t":"For in Christ Jesus neither is circumcision anything, nor uncircumcision, but a new creation."},{"v":16,"t":"As many as walk by this rule, peace and mercy be on them, and on God’s Israel."},{"v":17,"t":"From now on, let no one cause me any trouble, for I bear the marks of the Lord Jesus branded on my body."},{"v":18,"t":"The grace of our Lord Jesus Christ be with your spirit, brothers. Amen."}],"hr":[{"v":1,"t":"Braćo, ako se tko i zatekne u kakvu prijestupu, vi, duhovni, takva ispravljajte u duhu blagosti. A pazi na samoga sebe da i ti ne podlegneš napasti."},{"v":2,"t":"Nosite jedni bremena drugih i tako ćete ispuniti zakon Kristov!"},{"v":3,"t":"Jer misli li tko da jest štogod, a nije ništa, sam sebe vara."},{"v":4,"t":"Svatko neka ispita sam svoje djelo pa će onda u samom sebi imati čime se dičiti, a ne u usporedbi s drugim."},{"v":5,"t":"Ta svatko će nositi svoj teret."},{"v":6,"t":"Koji se uči Riječi, neka sva dobra dijeli sa svojim učiteljem."},{"v":7,"t":"Ne varajte se: Bog se ne da izrugivati! Što tko sije, to će i žeti!"},{"v":8,"t":"Doista, tko sije u tijelo svoje, iz tijela će žeti raspadljivost, a tko sije u duh, iz duha će žeti život vječni."},{"v":9,"t":"Neka nam ne dozlogrdi činiti dobro: ako ne sustanemo, u svoje ćemo vrijeme žeti!"},{"v":10,"t":"Dakle, dok imamo vremena, činimo dobro svima, ponajpače domaćima u vjeri."},{"v":11,"t":"Gledajte kolikim vam slovima pišem svojom rukom."},{"v":12,"t":"Svi koji se hoće praviti važni tijelom, sile vas na obrezanje, samo da zbog križa Kristova ne bi trpjeli progonstvo."},{"v":13,"t":"Ta ni sami obrezani ne opslužuju Zakona, ali hoće da se vi obrežete da bi se mogli ponositi vašim tijelom."},{"v":14,"t":"A ja, Bože sačuvaj da bih se ičim ponosio osim križem Gospodina našega Isusa Krista po kojem je meni svijet raspet i ja svijetu."},{"v":15,"t":"Uistinu, niti je što obrezanje niti neobrezanje, nego - novo stvorenje."},{"v":16,"t":"A na sve koji se ovoga pravila budu držali, i na sveg Izraela Božjega - mir i milosrđe!"},{"v":17,"t":"Ubuduće neka mi nitko ne dodijava jer ja na svom tijelu nosim biljege Isusove!"},{"v":18,"t":"Milost Gospodina našega Isusa Krista s duhom vašim, braćo! Amen"}]}},"EPH":{"1":{"fa":[{"v":1,"t":"پولس به اراده خدا رسول عیسی مسیح، به مقدسینی که در افسس می‌باشند وایمانداران در مسیح عیسی."},{"v":2,"t":"فیض و سلامتی از جانب پدر ما خدا وعیسی مسیح خداوند بر شما باد."},{"v":3,"t":"متبارک باد خدا و پدر خداوند ما عیسی مسیح که ما را مبارک ساخت به هر برکت روحانی در جایهای آسمانی در مسیح."},{"v":4,"t":"چنانکه ما راپیش از بنیاد عالم در او برگزید تا در حضور او درمحبت مقدس و بی‌عیب باشیم."},{"v":5,"t":"که ما را از قبل تعیین نمود تا او را پسر خوانده شویم بوساطت عیسی مسیح برحسب خشنودی اراده خود،"},{"v":6,"t":"برای ستایش جلال فیض خود که ما را به آن مستفیض گردانید در آن حبیب."},{"v":7,"t":"که در وی به‌سبب خون او فدیه یعنی آمرزش گناهان را به اندازه دولت فیض او یافته‌ایم."},{"v":8,"t":"که آن را به ما به فراوانی عطا فرمود در حکمت و فطانت."},{"v":9,"t":"چونکه سر اراده خود را به ما شناسانید، برحسب خشنودی خود که در خود عزم نموده بود،"},{"v":10,"t":"برای انتظام کمال زمانها تا همه‌چیز را خواه آنچه در آسمان و خواه آنچه بر زمین است، درمسیح جمع کند، یعنی در او."},{"v":11,"t":"که ما نیز در وی میراث او شده‌ایم، چنانکه پیش معین گشتیم برحسب قصد او. که همه‌چیزها را موافق رای اراده خود می‌کند."},{"v":12,"t":"تا از ما که اول امیدوار به مسیح می‌بودیم، جلال او ستوده شود."},{"v":13,"t":"و دروی شما نیز چون کلام راستی، یعنی بشارت نجات خود را شنیدید، در وی چون ایمان آوردید، از روح قدوس وعده مختوم شدید."},{"v":14,"t":"که بیعانه میراث ما است برای فدای آن ملک خاص او تا جلال او ستوده شود."},{"v":15,"t":"بنابراین، من نیز چون خبر ایمان شما را درعیسی خداوند ومحبت شما را با همه مقدسین شنیدم،"},{"v":16,"t":"باز نمی ایستم از شکر نمودن برای شما و از یاد آوردن شما در دعاهای خود،"},{"v":17,"t":"تاخدای خداوند ما عیسی مسیح که پدر ذوالجلال است، روح حکمت و کشف را در معرفت خود به شما عطا فرماید."},{"v":18,"t":"تا چشمان دل شما روشن گشته، بدانید که امید دعوت او چیست و کدام است دولت جلال میراث او در مقدسین،"},{"v":19,"t":"و چه مقدار است عظمت بینهایت قوت او نسبت به مامومنین برحسب عمل توانایی قوت او"},{"v":20,"t":"که درمسیح عمل کرد چون او را از مردگان برخیزانید وبه‌دست راست خود در جایهای آسمانی نشانید،"},{"v":21,"t":"بالاتر از هر ریاست و قدرت و قوت و سلطنت و هر نامی که خوانده می‌شود، نه در این عالم فقطبلکه در عالم آینده نیز."},{"v":22,"t":"و همه‌چیز را زیر پایهای او نهاد و او را سرهمه‌چیز به کلیسا داد،"},{"v":23,"t":"که بدن اوست یعنی پری او که همه را در همه پر می‌سازد."}],"en":[{"v":1,"t":"Paul, an apostle of Christ Jesus through the will of God, to the saints who are at Ephesus, and the faithful in Christ Jesus:"},{"v":2,"t":"Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":3,"t":"Blessed be the God and Father of our Lord Jesus Christ, who has blessed us with every spiritual blessing in the heavenly places in Christ,"},{"v":4,"t":"even as he chose us in him before the foundation of the world, that we would be holy and without defect before him in love,"},{"v":5,"t":"having predestined us for adoption as children through Jesus Christ to himself, according to the good pleasure of his desire,"},{"v":6,"t":"to the praise of the glory of his grace, by which he freely gave us favor in the Beloved."},{"v":7,"t":"In him we have our redemption through his blood, the forgiveness of our trespasses, according to the riches of his grace"},{"v":8,"t":"which he made to abound toward us in all wisdom and prudence,"},{"v":9,"t":"making known to us the mystery of his will, according to his good pleasure which he purposed in him"},{"v":10,"t":"to an administration of the fullness of the times, to sum up all things in Christ, the things in the heavens and the things on the earth, in him."},{"v":11,"t":"We were also assigned an inheritance in him, having been foreordained according to the purpose of him who does all things after the counsel of his will,"},{"v":12,"t":"to the end that we should be to the praise of his glory, we who had before hoped in Christ."},{"v":13,"t":"In him you also, having heard the word of the truth, the Good News of your salvation—in whom, having also believed, you were sealed with the promised Holy Spirit,"},{"v":14,"t":"who is a pledge of our inheritance, to the redemption of God’s own possession, to the praise of his glory."},{"v":15,"t":"For this cause I also, having heard of the faith in the Lord Jesus which is among you and the love which you have toward all the saints,"},{"v":16,"t":"don’t cease to give thanks for you, making mention of you in my prayers,"},{"v":17,"t":"that the God of our Lord Jesus Christ, the Father of glory, may give to you a spirit of wisdom and revelation in the knowledge of him,"},{"v":18,"t":"having the eyes of your hearts enlightened, that you may know what is the hope of his calling, and what are the riches of the glory of his inheritance in the saints,"},{"v":19,"t":"and what is the exceeding greatness of his power toward us who believe, according to that working of the strength of his might"},{"v":20,"t":"which he worked in Christ when he raised him from the dead and made him to sit at his right hand in the heavenly places,"},{"v":21,"t":"far above all rule, authority, power, dominion, and every name that is named, not only in this age, but also in that which is to come."},{"v":22,"t":"He put all things in subjection under his feet, and gave him to be head over all things for the assembly,"},{"v":23,"t":"which is his body, the fullness of him who fills all in all."}],"hr":[{"v":1,"t":"Pavao, po volji Božjoj apostol Krista Isusa: svetima koji su u Efezu i vjernima u Isusu Kristu."},{"v":2,"t":"Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista!"},{"v":3,"t":"Blagoslovljen Bog i Otac Gospodina našega Isusa Krista, on koji nas blagoslovi svakim blagoslovom duhovnim u nebesima, u Kristu."},{"v":4,"t":"Tako: u njemu nas sebi izabra prije postanka svijeta da budemo sveti i bez mane pred njim;"},{"v":5,"t":"u ljubavi nas predodredi za posinstvo, za sebe, po Isusu Kristu, dobrohotnošću svoje volje,"},{"v":6,"t":"na hvalu Slave svoje milosti. Njome nas zamilova u Ljubljenome"},{"v":7,"t":"u kome, njegovom krvlju, imamo otkupljenje, otpuštenje prijestupa po bogatstvu njegove milosti."},{"v":8,"t":"Nju preobilno u nas uli zajedno sa svom mudrošću i razumijevanjem"},{"v":9,"t":"obznanivši nam otajstvo svoje volje po dobrohotnom naumu svojem što ga prije u njemu zasnova"},{"v":10,"t":"da se provede punina vremena: uglaviti u Kristu sve - na nebesima i na zemlji."},{"v":11,"t":"U njemu, u kome i nama - predodređenima po naumu Onoga koji sve izvodi po odluci svoje volje - u dio pade"},{"v":12,"t":"da budemo na hvalu Slave njegove - mi koji smo se već prije nadali u Kristu."},{"v":13,"t":"U njemu ste i vi, pošto ste čuli Riječ istine - evanđelje spasenja svoga - u njemu ste, prigrlivši vjeru, opečaćeni Duhom obećanim, Svetim,"},{"v":14,"t":"koji je zalog naše baštine: otkupljenja, posvojenja - na hvalu Slave njegove."},{"v":15,"t":"Zato i ja, otkad sam čuo za vašu vjeru u Gospodinu Isusu i za ljubav prema svima svetima,"},{"v":16,"t":"ne prestajem zahvaljivati za vas i sjećati vas se u svojim molitvama:"},{"v":17,"t":"Bog Gospodina našega Isusa Krista, Otac Slave, dao vam Duha mudrosti i objave kojom ćete ga spoznati;"},{"v":18,"t":"prosvijetlio vam oči srca da upoznate koje li nade u pozivu njegovu, koje li bogate slave u baštini njegovoj među svetima"},{"v":19,"t":"i koje li prekomjerne veličine u moći njegovoj prema nama koji vjerujemo: ona je primjerena djelotvornosti sile i snage njegove"},{"v":20,"t":"koju na djelu pokaza u Kristu, kad ga uskrisi od mrtvih i posjede sebi zdesna na nebesima"},{"v":21,"t":"iznad svakog Vrhovništva i Vlasti i Moći i Gospodstva i svakog imena imenovana ne samo na ovom svijetu nego i u budućemu."},{"v":22,"t":"Sve mu podloži pod noge, a njega postavi - nad svime - Glavom Crkvi,"},{"v":23,"t":"koja je Tijelo njegovo, punina Onoga koji sve u svima ispunja."}]},"2":{"fa":[{"v":1,"t":"و شما را که در خطایا و گناهان مرده بودید، زنده گردانید،"},{"v":2,"t":"که در آنها قبل، رفتارمی کردید برحسب دوره این جهان بر وفق رئیس قدرت هوا یعنی آن روحی که الحال در فرزندان معصیت عمل می‌کند."},{"v":3,"t":"که در میان ایشان، همه مانیز در شهوات جسمانی خود قبل از این زندگی می‌کردیدم و هوسهای جسمانی و افکار خود رابه عمل می‌آوردیم و طبع فرزندان غضب بودیم، چنانکه دیگران."},{"v":4,"t":"لیکن خدا که در رحمانیت، دولتمند است، از حیثیت محبت عظیم خود که باما نمود،"},{"v":5,"t":"ما را نیز که در خطایا مرده بودیم بامسیح زنده گردانید، زیرا که محض فیض نجات یافته‌اید."},{"v":6,"t":"و با او برخیزانید و در جایهای آسمانی در مسیح عیسی نشانید."},{"v":7,"t":"تا در عالمهای آینده دولت بینهایت فیض خود را به لطفی که بر ما درمسیح عیسی دارد ظاهر سازد."},{"v":8,"t":"زیرا که محض فیض نجات یافته‌اید، بوسیله ایمان و این از شمانیست بلکه بخشش خداست،"},{"v":9,"t":"و نه از اعمال تاهیچ‌کس فخر نکند."},{"v":10,"t":"زیرا که صنعت او هستیم، آفریده شده در مسیح عیسی برای کارهای نیکوکه خدا قبل مهیا نمود تا در آنها سلوک نماییم."},{"v":11,"t":"لهذا به یاد آورید که شما در زمان سلف (ای امت های در جسم که آنانی که به اهل ختنه نامیده می‌شوند، اما ختنه ایشان در جسم وساخته شده به‌دست است، شما را نامختون می‌خوانند)،"},{"v":12,"t":"که شما در آن زمان از مسیح جداو از وطنیت خاندان اسرائیل، اجنبی و ازعهدهای وعده بیگانه و بی‌امید و بی‌خدا در دنیابودید."},{"v":13,"t":"لیکن الحال در مسیح عیسی شما که درآن وقت دور بودید، به خون مسیح نزدیک شده‌اید."},{"v":14,"t":"زیرا که او سلامتی ما است که هر دورا یک گردانید و دیوار جدایی را که در میان بودمنهدم ساخت،"},{"v":15,"t":"و عداوت یعنی شریعت احکام را که در فرایض بود، به جسم خود نابودساخت تا که مصالحه کرده، از هر دو یک انسان جدید در خود بیافریند."},{"v":16,"t":"و تا هر دو را در یک جسد با خدا مصالحه دهد، بوساطت صلیب خودکه بر آن عداوت را کشت،"},{"v":17,"t":"و آمده بشارت مصالحه را رسانید به شما که دور بودید ومصالحه را به آنانی که نزدیک بودند."},{"v":18,"t":"زیرا که بوسیله او هردو نزد پدر در یک روح دخول داریم."},{"v":19,"t":"پس از این به بعد غریب و اجنبی نیستیدبلکه هموطن مقدسین هستید و از اهل خانه خدا."},{"v":20,"t":"و بر بنیاد رسولان و انبیا بنا شده‌اید که خودعیسی مسیح سنگ زاویه است."},{"v":21,"t":"که در وی تمامی عمارت با هم مرتب شده، به هیکل مقدس در خداوند نمو می‌کند."},{"v":22,"t":"و در وی شما نیز با هم بنا کرده می‌شوید تا در روح مسکن خدا شوید."}],"en":[{"v":1,"t":"You were made alive when you were dead in transgressions and sins,"},{"v":2,"t":"in which you once walked according to the course of this world, according to the prince of the power of the air, the spirit who now works in the children of disobedience."},{"v":3,"t":"We also all once lived among them in the lusts of our flesh, doing the desires of the flesh and of the mind, and were by nature children of wrath, even as the rest."},{"v":4,"t":"But God, being rich in mercy, for his great love with which he loved us,"},{"v":5,"t":"even when we were dead through our trespasses, made us alive together with Christ—by grace you have been saved—"},{"v":6,"t":"and raised us up with him, and made us to sit with him in the heavenly places in Christ Jesus,"},{"v":7,"t":"that in the ages to come he might show the exceeding riches of his grace in kindness toward us in Christ Jesus;"},{"v":8,"t":"for by grace you have been saved through faith, and that not of yourselves; it is the gift of God,"},{"v":9,"t":"not of works, that no one would boast."},{"v":10,"t":"For we are his workmanship, created in Christ Jesus for good works, which God prepared before that we would walk in them."},{"v":11,"t":"Therefore remember that once you, the Gentiles in the flesh, who are called “uncircumcision” by that which is called “circumcision” (in the flesh, made by hands),"},{"v":12,"t":"that you were at that time separate from Christ, alienated from the commonwealth of Israel, and strangers from the covenants of the promise, having no hope and without God in the world."},{"v":13,"t":"But now in Christ Jesus you who once were far off are made near in the blood of Christ."},{"v":14,"t":"For he is our peace, who made both one, and broke down the middle wall of separation,"},{"v":15,"t":"having abolished in his flesh the hostility, the law of commandments contained in ordinances, that he might create in himself one new man of the two, making peace,"},{"v":16,"t":"and might reconcile them both in one body to God through the cross, having killed the hostility through it."},{"v":17,"t":"He came and preached peace to you who were far off and to those who were near."},{"v":18,"t":"For through him we both have our access in one Spirit to the Father."},{"v":19,"t":"So then you are no longer strangers and foreigners, but you are fellow citizens with the saints and of the household of God,"},{"v":20,"t":"being built on the foundation of the apostles and prophets, Christ Jesus himself being the chief cornerstone;"},{"v":21,"t":"in whom the whole building, fitted together, grows into a holy temple in the Lord;"},{"v":22,"t":"in whom you also are built together for a habitation of God in the Spirit."}],"hr":[{"v":1,"t":"I vi bijaste mrtvi zbog prijestupa i grijeha"},{"v":2,"t":"u kojima ste nekoć živjeli po Eonu ovoga svijeta, po Knezu vlasti zraka, po tomu duhu koji sada djeluje u sinovima neposlušnima."},{"v":3,"t":"Među njima smo i mi nekoć živjeli u požudama tijela svoga, udovoljavajući prohtjevima tijela i ćudi, te po naravi bijasmo djeca gnjeva kao i drugi."},{"v":4,"t":"Ali Bog, bogat milosrđem, zbog velike ljubavi kojom nas uzljubi,"},{"v":5,"t":"nas koji bijasmo mrtvi zbog prijestupa, oživi zajedno s Kristom - milošću ste spašeni! -"},{"v":6,"t":"te nas zajedno s njim uskrisi i posadi na nebesima u Kristu Isusu:"},{"v":7,"t":"da u dobrohotnosti prema nama u Kristu Isusu pokaže budućim vjekovima preobilno bogatstvo milosti svoje."},{"v":8,"t":"Ta milošću ste spašeni po vjeri! I to ne po sebi! Božji je to dar!"},{"v":9,"t":"Ne po djelima, da se ne bi tko hvastao."},{"v":10,"t":"Njegovo smo djelo, stvoreni u Kristu Isusu za dobra djela, koja Bog unaprijed pripravi da u njima živimo."},{"v":11,"t":"Spominjite se stoga da nekoć bijaste neznabošci u tijelu - neobrezanicima su vas zvali oni koji se zovu obrezani, rukom, na tijelu -"},{"v":12,"t":"i da u ono vrijeme bijaste izvan Krista, udaljeni od građanstva izraelskoga, tuđi Savezima obećanja, bez nade bijaste i neznabošci na svijetu."},{"v":13,"t":"Sada pak, u Kristu Isusu, vi koji nekoć bijaste daleko, dođoste blizu - po Krvi Kristovoj."},{"v":14,"t":"Doista, on je mir naš, on koji od dvoga učini jedno: pregradu razdvojnicu, neprijateljstvo razori u svome tijelu."},{"v":15,"t":"Zakon zapovijedi s propisima obeskrijepi da u sebi, uspostavljajući mir, od dvojice sazda jednoga novog čovjeka"},{"v":16,"t":"te obojicu u jednome Tijelu izmiri s Bogom po križu, ubivši u sebi neprijateljstvo."},{"v":17,"t":"I dođe te navijesti mir vama daleko i mir onima blizu,"},{"v":18,"t":"jer po njemu jedni i drugi u jednome Duhu imamo pristup Ocu."},{"v":19,"t":"Tako dakle više niste tuđinci ni pridošlice, nego sugrađani ste svetih i ukućani Božji"},{"v":20,"t":"nazidani na temelju apostola i proroka, a zaglavni je kamen sam Krist Isus."},{"v":21,"t":"U njemu je sva građevina povezana i raste u hram svet u Gospodinu."},{"v":22,"t":"U njemu ste i vi ugrađeni u prebivalište Božje u Duhu."}]},"3":{"fa":[{"v":1,"t":"از این سبب من که پولس هستم و اسیر مسیح عیسی برای شما‌ای امت ها-"},{"v":2,"t":"اگر شنیده باشید تدبیر فیض خدا را که بجهت شما به من عطا شده است،"},{"v":3,"t":"که این سر ازراه کشف بر من اعلام شد، چنانکه مختصر پیش نوشتم،"},{"v":4,"t":"و از مطالعه آن می‌توانید ادراک مرا درسر میسح بفهمید."},{"v":5,"t":"که آن در قرنهای گذشته به بنی آدم آشکار نشده بود، بطوری که الحال بررسولان مقدس و انبیای او به روح مکشوف گشته است،"},{"v":6,"t":"که امت‌ها در میراث و در بدن و در بهره وعده او در مسیح بوساطت انجیل شریک هستند."},{"v":7,"t":"که خادم آن شدم بحسب عطای فیض خدا که برحسب عمل قوت او به من داده شده است."},{"v":8,"t":"یعنی به من که کمتر از کمترین همه مقدسینم، این فیض عطا شد که در میان امت‌ها به دولت بی‌قیاس مسیح بشارت دهم،"},{"v":9,"t":"و همه را روشن سازم که چیست انتظام آن سری که از بنای عالمهامستور بود، در خدایی که همه‌چیز را بوسیله عیسی مسیح آفرید."},{"v":10,"t":"تا آنکه الحال بر ارباب ریاستها و قدرتها در جایهای آسمانی، حکمت گوناگون خدا بوسیله کلیسا معلوم شود،"},{"v":11,"t":"برحسب تقدیر ازلی که در خداوند ما مسیح عیسی نمود،"},{"v":12,"t":"که در وی جسارت و دخول بااعتماد داریم به‌سبب ایمان وی."},{"v":13,"t":"لهذا استدعادارم که از زحمات من به جهت شما خسته خاطرمشوید که آنها فخر شما است."},{"v":14,"t":"از این سبب، زانو می‌زنم نزد آن پدر،"},{"v":15,"t":"که از او هر خانواده‌ای در آسمان و بر زمین مسمی می‌شود؛"},{"v":16,"t":"که بحسب دولت جلال خود به شماعطا کند که در انسانیت باطنی خود از روح او به قوت زورآور شوید،"},{"v":17,"t":"تا مسیح به وساطت ایمان در دلهای شما ساکن شود؛"},{"v":18,"t":"و در محبت ریشه کرده و بنیاد نهاده، استطاعت یابید که باتمامی مقدسین ادراک کنید که عرض و طول وعمق و بلندی چیست؛"},{"v":19,"t":"و عارف شوید به محبت مسیح که فوق از معرفت است تا پر شویدتا تمامی پری خدا."},{"v":20,"t":"الحال او را که قادر است که بکند بینهایت زیادتر از هرآنچه بخواهیم یا فکر کنیم، بحسب آن قوتی که در ما عمل می‌کند،"},{"v":21,"t":"مر او را درکلیسا و در مسیح عیسی تا جمیع قرنها تا ابدالابادجلال باد. آمین."}],"en":[{"v":1,"t":"For this cause I, Paul, am the prisoner of Christ Jesus on behalf of you Gentiles,"},{"v":2,"t":"if it is so that you have heard of the administration of that grace of God which was given me toward you,"},{"v":3,"t":"how that by revelation the mystery was made known to me, as I wrote before in few words,"},{"v":4,"t":"by which, when you read, you can perceive my understanding in the mystery of Christ,"},{"v":5,"t":"which in other generations was not made known to the children of men, as it has now been revealed to his holy apostles and prophets in the Spirit,"},{"v":6,"t":"that the Gentiles are fellow heirs and fellow members of the body, and fellow partakers of his promise in Christ Jesus through the Good News,"},{"v":7,"t":"of which I was made a servant according to the gift of that grace of God which was given me according to the working of his power."},{"v":8,"t":"To me, the very least of all saints, was this grace given, to preach to the Gentiles the unsearchable riches of Christ,"},{"v":9,"t":"and to make all men see what is the administration of the mystery which for ages has been hidden in God, who created all things through Jesus Christ,"},{"v":10,"t":"to the intent that now through the assembly the manifold wisdom of God might be made known to the principalities and the powers in the heavenly places,"},{"v":11,"t":"according to the eternal purpose which he accomplished in Christ Jesus our Lord."},{"v":12,"t":"In him we have boldness and access in confidence through our faith in him."},{"v":13,"t":"Therefore I ask that you may not lose heart at my troubles for you, which are your glory."},{"v":14,"t":"For this cause, I bow my knees to the Father of our Lord Jesus Christ,"},{"v":15,"t":"from whom every family in heaven and on earth is named,"},{"v":16,"t":"that he would grant you, according to the riches of his glory, that you may be strengthened with power through his Spirit in the inner person,"},{"v":17,"t":"that Christ may dwell in your hearts through faith, to the end that you, being rooted and grounded in love,"},{"v":18,"t":"may be strengthened to comprehend with all the saints what is the width and length and height and depth,"},{"v":19,"t":"and to know Christ’s love which surpasses knowledge, that you may be filled with all the fullness of God."},{"v":20,"t":"Now to him who is able to do exceedingly abundantly above all that we ask or think, according to the power that works in us,"},{"v":21,"t":"to him be the glory in the assembly and in Christ Jesus to all generations, forever and ever. Amen."}],"hr":[{"v":1,"t":"Radi toga ja, Pavao, sužanj Krista Isusa za vas pogane..."},{"v":2,"t":"Zacijelo ste čuli za rasporedbu milosti Božje koja mi je dana za vas:"},{"v":3,"t":"objavom mi je obznanjeno otajstvo, kako netom ukratko opisah."},{"v":4,"t":"Čitajući to, možete dokučiti kako ja shvaćam Kristovo otajstvo,"},{"v":5,"t":"koje nije bilo obznanjeno sinovima ljudskim drugih naraštaja. Ono je sada u Duhu objavljeno svetim njegovim apostolima i prorocima:"},{"v":6,"t":"da su pogani subaštinici i “sutijelo” i sudionici obećanja u Kristu Isusu - po evanđelju,"},{"v":7,"t":"kojega postadoh poslužiteljem darom milosti Božje koja mi je dana djelotvornošću snage njegove."},{"v":8,"t":"Meni, najmanjemu od svih svetih, dana je ova milost: poganima biti blagovjesnikom neistraživog bogatstva Kristova"},{"v":9,"t":"i osvijetliti rasporedbu otajstva, pred vjekovima skrivena u Bogu, koji sve stvori,"},{"v":10,"t":"da sada - po Crkvi - Vrhovništvima i Vlastima na nebesima bude obznanjena mnogolika mudrost Božja"},{"v":11,"t":"zasnovana - po naumu o vjekovima - u Kristu Isusu Gospodinu našemu."},{"v":12,"t":"U njemu, s pouzdanjem po vjeri u njega, imamo slobodan pristup."},{"v":13,"t":"Zato ne klonite, molim, s nevolja mojih za vas! One su slava vaša!"},{"v":14,"t":"Zato prigibam koljena pred Ocem,"},{"v":15,"t":"od koga ime svakom očinstvu na nebu i na zemlji:"},{"v":16,"t":"neka vam dadne po bogatstvu Slave svoje ojačati se po Duhu njegovu u snazi za unutarnjeg čovjeka"},{"v":17,"t":"da po vjeri Krist prebiva u srcima vašim te u ljubavi ukorijenjeni i utemeljeni"},{"v":18,"t":"mognete shvatiti sa svima svetima što je Dužina i Širina i Visina i Dubina"},{"v":19,"t":"te spoznati nadspoznatljivu ljubav Kristovu da se ispunite do sve Punine Božje."},{"v":20,"t":"Onomu pak koji snagom u nama djelatnom može učiniti mnogo izobilnije nego li mi moliti ili zamisliti -"},{"v":21,"t":"Njemu slava u Crkvi i u Kristu Isusu za sva pokoljenja vijeka vjekovječnoga! Amen."}]},"4":{"fa":[{"v":1,"t":"لهذا من که در خداوند اسیر می‌باشم، ازشما استدعا دارم که به شایستگی آن دعوتی که به آن خوانده شده‌اید، رفتار کنید،"},{"v":2,"t":"باکمال فروتنی و تواضع و حلم، و متحمل یکدیگردر محبت باشید؛"},{"v":3,"t":"و سعی کنید که یگانگی روح را در رشته سلامتی نگاه دارید."},{"v":4,"t":"یک جسدهست و یک روح، چنانکه نیز دعوت شده‌اید دریک امید دعوت خویش."},{"v":5,"t":"یک خداوند، یک ایمان، یک تعمید؛"},{"v":6,"t":"یک خدا و پدر همه که فوق همه و در میان همه و در همه شما است."},{"v":7,"t":"لیکن هریکی از ما را فیض بخشیده شد بحسب اندازه بخشش مسیح."},{"v":8,"t":"بنابراین می‌گوید: «چون او به اعلی علیین صعود نمود، اسیری را به اسیری برد و بخششها به مردم داد.»"},{"v":9,"t":"اما این صعود نمودچیست؟ جز اینکه اول نزول هم کرد به اسفل زمین."},{"v":10,"t":"آنکه نزول نمود، همان است که صعودنیز کرد بالاتر از جمیع افلاک تا همه‌چیزها را پرکند."},{"v":11,"t":"و او بخشید بعضی رسولان و بعضی انبیا وبعضی مبشرین و بعضی شبانان و معلمان را،"},{"v":12,"t":"برای تکمیل مقدسین، برای کار خدمت، برای بنای جسد مسیح،"},{"v":13,"t":"تا همه به یگانگی ایمان ومعرفت تام پسر خدا و به انسان کامل، به اندازه قامت پری مسیح برسیم."},{"v":14,"t":"تا بعد از این اطفال متموج و رانده شده از باد هر تعلیم نباشیم، ازدغابازی مردمان در حیله اندیشی برای مکرهای گمراهی؛"},{"v":15,"t":"بلکه در محبت پیروی راستی نموده، در هرچیز ترقی نماییم در او که سر است، یعنی مسیح؛"},{"v":16,"t":"که از او تمام بدن مرکب و مرتب گشته، به مدد هر مفصلی و برحسب عمل به اندازه هرعضوی بدن را نمو می‌دهد برای بنای خویشتن در محبت."},{"v":17,"t":"پس این را می‌گویم و در خداوند شهادت می‌دهم که شما دیگر رفتار منمایید، چنانکه امت‌ها در بطالت ذهن خود رفتار می‌نمایند."},{"v":18,"t":"که در عقل خود تاریک هستند و از حیات خدامحروم، به‌سبب جهالتی که بجهت سخت دلی ایشان در ایشان است."},{"v":19,"t":"که بی‌فکر شده، خود رابه فجور تسلیم کرده‌اند تا هرقسم ناپاکی را به حرص به عمل آورند."},{"v":20,"t":"لیکن شما مسیح را به اینطور نیاموخته‌اید."},{"v":21,"t":"هرگاه او را شنیده‌اید و در او تعلیم یافته‌اید، به نهجی که راستی در عیسی است."},{"v":22,"t":"تا آنکه شمااز جهت رفتار گذشته خود، انسانیت کهنه را که ازشهوات فریبنده فاسد می‌گردد، از خود بیرون کنید."},{"v":23,"t":"و به روح ذهن خود تازه شوید."},{"v":24,"t":"وانسانیت تازه را که به صورت خدا در عدالت وقدوسیت حقیقی آفریده شده است بپوشید."},{"v":25,"t":"لهذا دروغ را ترک کرده، هرکس با همسایه خود راست بگوید، زیرا که ما اعضای یکدیگریم."},{"v":26,"t":"خشم گیرید و گناه مورزید؛ خورشید بر غیظشما غروب نکند."},{"v":27,"t":"ابلیس را مجال ندهید."},{"v":28,"t":"دزد دیگر دزدی نکند بلکه به‌دستهای خود کارنیکو کرده، زحمت بکشد تا بتواند نیازمندی راچیزی دهد."},{"v":29,"t":"هیچ سخن بد از دهان شما بیرون نیاید، بلکه آنچه بحسب حاجت و برای بنا نیکوباشد تا شنوندگان را فیض رساند."},{"v":30,"t":"و روح قدوس خدا را که به او تا روز رستگاری مختوم شده‌اید، محزون مسازید."},{"v":31,"t":"و هرقسم تلخی وغیظ و خشم و فریاد و بدگویی و خباثت را ازخود دور کنید،"},{"v":32,"t":"و با یگدیگر مهربان باشید ورحیم و همدیگر را عفو نمایید چنانکه خدا درمسیح شما را هم آمرزیده است."}],"en":[{"v":1,"t":"I therefore, the prisoner in the Lord, beg you to walk worthily of the calling with which you were called,"},{"v":2,"t":"with all lowliness and humility, with patience, bearing with one another in love,"},{"v":3,"t":"being eager to keep the unity of the Spirit in the bond of peace."},{"v":4,"t":"There is one body and one Spirit, even as you also were called in one hope of your calling,"},{"v":5,"t":"one Lord, one faith, one baptism,"},{"v":6,"t":"one God and Father of all, who is over all and through all and in us all."},{"v":7,"t":"But to each one of us, the grace was given according to the measure of the gift of Christ."},{"v":8,"t":"Therefore he says, “When he ascended on high, he led captivity captive, and gave gifts to people.”"},{"v":9,"t":"Now this, “He ascended”, what is it but that he also first descended into the lower parts of the earth?"},{"v":10,"t":"He who descended is the one who also ascended far above all the heavens, that he might fill all things."},{"v":11,"t":"He gave some to be apostles; and some, prophets; and some, evangelists; and some, shepherds and teachers;"},{"v":12,"t":"for the perfecting of the saints, to the work of serving, to the building up of the body of Christ,"},{"v":13,"t":"until we all attain to the unity of the faith and of the knowledge of the Son of God, to a full grown man, to the measure of the stature of the fullness of Christ,"},{"v":14,"t":"that we may no longer be children, tossed back and forth and carried about with every wind of doctrine, by the trickery of men, in craftiness, after the wiles of error;"},{"v":15,"t":"but speaking truth in love, we may grow up in all things into him who is the head, Christ,"},{"v":16,"t":"from whom all the body, being fitted and knit together through that which every joint supplies, according to the working in measure of each individual part, makes the body increase to the building up of itself in love."},{"v":17,"t":"This I say therefore, and testify in the Lord, that you no longer walk as the rest of the Gentiles also walk, in the futility of their mind,"},{"v":18,"t":"being darkened in their understanding, alienated from the life of God because of the ignorance that is in them, because of the hardening of their hearts."},{"v":19,"t":"They, having become callous, gave themselves up to lust, to work all uncleanness with greediness."},{"v":20,"t":"But you didn’t learn Christ that way,"},{"v":21,"t":"if indeed you heard him and were taught in him, even as truth is in Jesus:"},{"v":22,"t":"that you put away, as concerning your former way of life, the old man that grows corrupt after the lusts of deceit,"},{"v":23,"t":"and that you be renewed in the spirit of your mind,"},{"v":24,"t":"and put on the new man, who in the likeness of God has been created in righteousness and holiness of truth."},{"v":25,"t":"Therefore, putting away falsehood, speak truth each one with his neighbor, for we are members of one another."},{"v":26,"t":"“Be angry, and don’t sin.” Don’t let the sun go down on your wrath,"},{"v":27,"t":"and don’t give place to the devil."},{"v":28,"t":"Let him who stole steal no more; but rather let him labor, producing with his hands something that is good, that he may have something to give to him who has need."},{"v":29,"t":"Let no corrupt speech proceed out of your mouth, but only what is good for building others up as the need may be, that it may give grace to those who hear."},{"v":30,"t":"Don’t grieve the Holy Spirit of God, in whom you were sealed for the day of redemption."},{"v":31,"t":"Let all bitterness, wrath, anger, outcry, and slander be put away from you, with all malice."},{"v":32,"t":"And be kind to one another, tender hearted, forgiving each other, just as God also in Christ forgave you."}],"hr":[{"v":1,"t":"Zaklinjem vas dakle ja, sužanj u Gospodinu: sa svom poniznošću i blagošću, sa strpljivošću živite dostojno poziva kojim ste pozvani!"},{"v":2,"t":"Podnosite jedni druge u ljubavi;"},{"v":3,"t":"trudite se sačuvati jedinstvo Duha svezom mira!"},{"v":4,"t":"Jedno tijelo i jedan Duh - kao što ste i pozvani na jednu nadu svog poziva!"},{"v":5,"t":"Jedan Gospodin! Jedna vjera! Jedan krst!"},{"v":6,"t":"Jedan Bog i Otac sviju, nad svima i po svima i u svima!"},{"v":7,"t":"A svakomu je od nas dana milost po mjeri dara Kristova."},{"v":8,"t":"Zato veli: Na visinu uzađe vodeći sužnje, dade dare ljudima."},{"v":9,"t":"Ono “uzađe” - što drugo znači doli to da i siđe u donje krajeve, na zemlju?"},{"v":10,"t":"Koji siđe, isti je onaj koji i uzađe ponad svih nebesa da sve ispuni."},{"v":11,"t":"On i “dade” jedne za apostole, druge za proroke, jedne opet za evanđeliste, a druge za pastire i učitelje"},{"v":12,"t":"da opremi svete za djelo služenja, za izgrađivanje Tijela Kristova"},{"v":13,"t":"dok svi ne prispijemo do jedinstva vjere i spoznaje Sina Božjega, do čovjeka savršena, do mjere uzrasta punine Kristove:"},{"v":14,"t":"da više ne budemo nejačad kojom se valovi poigravaju i koje goni svaki vjetar nauka u ovom kockanju ljudskom, u lukavosti što put krči zabludi."},{"v":15,"t":"Nego, istinujući u ljubavi da poradimo te sve uzraste u Njega, koji je Glava, Krist,"},{"v":16,"t":"od kojega sve Tijelo, usklađeno i povezano svakovrsnim zglobom zbrinjavanja po djelotvornosti primjerenoj svakomu pojedinom dijelu, promiče svoj rast na saziđivanje u ljubavi."},{"v":17,"t":"Ovo govorim i zaklinjem u Gospodinu: ne živite više kao što pogani žive - u ispraznosti pameti njihove:"},{"v":18,"t":"zamračena uma, udaljeni od života Božjega, sve zbog neznanja koje je u njima, zbog okorjelosti srca njihova."},{"v":19,"t":"Sami su sebe otupili i podali se razvratnosti da bi u pohlepi počinjali svaku nečistoću."},{"v":20,"t":"Vi pak ne naučiste tako Krista,"},{"v":21,"t":"ako ste ga doista čuli i u njemu bili poučeni kako je istina u Isusu:"},{"v":22,"t":"da vam je odložiti prijašnje ponašanje, starog čovjeka, koga varave požude vode u propast,"},{"v":23,"t":"a obnavljati se duhom svoje pameti"},{"v":24,"t":"i obući novog čovjeka, po Bogu stvorena u pravednosti i svetosti istine."},{"v":25,"t":"Zato odložite laž i govorite istinu jedan drugomu jer udovi smo jedni drugima."},{"v":26,"t":"Srdite se, ali ne griješite! Sunce nek ne zađe nad vašom srdžbom"},{"v":27,"t":"i ne dajite mjesta đavlu."},{"v":28,"t":"Tko je krao, neka više ne krade, nego neka se radije trudi svojim rukama priskrbljivati da ima što podijeliti s potrebnim."},{"v":29,"t":"Nikakva nevaljala riječ neka ne izlazi iz vaših usta, nego samo dobra, da prema potrebi saziđuje i milost iskaže slušateljima."},{"v":30,"t":"I ne žalostite Duha Svetoga, Božjega, kojim ste opečaćeni za Dan otkupljenja!"},{"v":31,"t":"Daleko od vas svaka gorčina, i srdžba, i gnjev, i vika, i hula sa svom opakošću!"},{"v":32,"t":"Naprotiv! Budite jedni drugima dobrostivi, milosrdni; praštajte jedni drugima kao što i Bog u Kristu nama oprosti."}]},"5":{"fa":[{"v":1,"t":"پس چون فرزندان عزیز به خدا اقتدا کنید."},{"v":2,"t":"و در محبت رفتار نمایید، چنانکه مسیح هم ما را محبت نمود و خویشتن را برای ما به خداهدیه و قربانی برای عطر خوشبوی گذرانید."},{"v":3,"t":"اما زنا و هر ناپاکی و طمع در میان شما هرگزمذکور هم نشود، چنانکه مقدسین را می‌شاید."},{"v":4,"t":"ونه قباحت و بیهوده‌گویی و چرب زبانی که اینها شایسته نیست بلکه شکرگزاری."},{"v":5,"t":"زیرا این را یقین می‌دانید که هیچ زانی یا ناپاک یا طماع که بت‌پرست باشد، میراثی در ملکوت مسیح و خداندارد."},{"v":6,"t":"هیچ‌کس شما را به سخنان باطل فریب ندهد، زیرا که به‌سبب اینها غضب خدا بر ابنای معصیت نازل می‌شود."},{"v":7,"t":"پس با ایشان شریک مباشید."},{"v":8,"t":"زیرا که پیشتر ظلمت بودید، لیکن الحال درخداوند نور می‌باشید. پس چون فرزندان نوررفتار کنید."},{"v":9,"t":"زیرا که میوه نور در کمال، نیکویی وعدالت و راستی است."},{"v":10,"t":"و تحقیق نمایید که پسندیده خداوند چیست."},{"v":11,"t":"و در اعمال بی‌ثمرظلمت شریک مباشید بلکه آنها را مذمت کنید،"},{"v":12,"t":"زیرا کارهایی که ایشان در خفا می‌کنند، حتی ذکر آنها هم قبیح است."},{"v":13,"t":"لیکن هرچیزی که مذمت شود، از نور ظاهر می‌گردد، زیرا که هرچه ظاهر می‌شود نور است."},{"v":14,"t":"بنابراین می‌گوید‌ای تو که خوابیده‌ای، بیدار شده، از مردگان برخیز تامسیح بر تو درخشد."},{"v":15,"t":"پس باخبر باشید که چگونه به دقت رفتارنمایید، نه چون جاهلان بلکه چون حکیمان."},{"v":16,"t":"ووقت را دریابید زیرا این‌روزها شریر است."},{"v":17,"t":"ازاین جهت بی‌فهم مباشید، بلکه بفهمید که اراده خداوند چیست."},{"v":18,"t":"و مست شراب مشوید که درآن فجور است، بلکه از روح پر شوید."},{"v":19,"t":"و بایکدیگر به مزامیر و تسبیحات و سرودهای روحانی گفتگو کنید و در دلهای خود به خداوندبسرایید و ترنم نمایید."},{"v":20,"t":"و پیوسته بجهت هرچیز خدا و پدر را به نام خداوند ما عیسی مسیح شکر کنید."},{"v":21,"t":"همدیگر را در خدا ترسی اطاعت کنید."},{"v":22,"t":"‌ای زنان، شوهران خود را اطاعت کنیدچنانکه خداوند را."},{"v":23,"t":"زیرا که شوهر سر زن است چنانکه مسیح نیز سر کلیسا و او نجات‌دهنده بدن است."},{"v":24,"t":"لیکن همچنانکه کلیسا مطیع مسیح است، همچنین زنان نیز شوهران خود را در هرامری باشند."},{"v":25,"t":"‌ای شوهران زنان خود را محبت نمایید، چنانکه مسیح هم کلیسا را محبت نمود وخویشتن را برای آن داد."},{"v":26,"t":"تا آن را به غسل آب بوسیله کلام طاهر ساخته، تقدیس نماید،"},{"v":27,"t":"تاکلیسای مجید را به نزد خود حاضر سازد که لکه وچین یا هیچ‌چیز مثل آن نداشته باشد، بلکه تامقدس و بی‌عیب باشد."},{"v":28,"t":"به همین طور، بایدمردان زنان خویش را مثل بدن خود محبت نمایند زیرا هرکه زوجه خود را محبت نماید، خویشتن را محبت می‌نماید."},{"v":29,"t":"زیرا هیچ‌کس هرگز جسم خود را دشمن نداشته است بلکه آن راتربیت و نوازش می‌کند، چنانکه خداوند نیزکلیسا را."},{"v":30,"t":"زانرو که اعضای بدن وی می‌باشیم، از جسم و از استخوانهای او."},{"v":31,"t":"از اینجاست که مرد پدر و مادر را رها کرده، با زوجه خویش خواهد پیوست و آن دو یکتن خواهند بود."},{"v":32,"t":"این سر، عظیم است، لیکن من درباره مسیح و کلیساسخن می‌گویم."},{"v":33,"t":"خلاصه هریکی از شما نیز زن خود را مثل نفس خود محبت بنماید و زن شوهر خود را باید احترام نمود."}],"en":[{"v":1,"t":"Be therefore imitators of God, as beloved children."},{"v":2,"t":"Walk in love, even as Christ also loved us and gave himself up for us, an offering and a sacrifice to God for a sweet-smelling fragrance."},{"v":3,"t":"But sexual immorality, and all uncleanness or covetousness, let it not even be mentioned among you, as becomes saints;"},{"v":4,"t":"nor filthiness, nor foolish talking, nor jesting, which are not appropriate, but rather giving of thanks."},{"v":5,"t":"Know this for sure, that no sexually immoral person, nor unclean person, nor covetous man (who is an idolater), has any inheritance in the Kingdom of Christ and God."},{"v":6,"t":"Let no one deceive you with empty words, for because of these things the wrath of God comes on the children of disobedience."},{"v":7,"t":"Therefore don’t be partakers with them."},{"v":8,"t":"For you were once darkness, but are now light in the Lord. Walk as children of light,"},{"v":9,"t":"for the fruit of the Spirit is in all goodness and righteousness and truth,"},{"v":10,"t":"proving what is well pleasing to the Lord."},{"v":11,"t":"Have no fellowship with the unfruitful deeds of darkness, but rather even reprove them."},{"v":12,"t":"For it is a shame even to speak of the things which are done by them in secret."},{"v":13,"t":"But all things, when they are reproved, are revealed by the light, for everything that reveals is light."},{"v":14,"t":"Therefore he says, “Awake, you who sleep, and arise from the dead, and Christ will shine on you.”"},{"v":15,"t":"Therefore watch carefully how you walk, not as unwise, but as wise,"},{"v":16,"t":"redeeming the time, because the days are evil."},{"v":17,"t":"Therefore, don’t be foolish, but understand what the will of the Lord is."},{"v":18,"t":"Don’t be drunken with wine, in which is dissipation, but be filled with the Spirit,"},{"v":19,"t":"speaking to one another in psalms, hymns, and spiritual songs; singing and making melody in your heart to the Lord;"},{"v":20,"t":"giving thanks always concerning all things in the name of our Lord Jesus Christ to God, even the Father;"},{"v":21,"t":"subjecting yourselves to one another in the fear of Christ."},{"v":22,"t":"Wives, be subject to your own husbands, as to the Lord."},{"v":23,"t":"For the husband is the head of the wife, as Christ also is the head of the assembly, being himself the savior of the body."},{"v":24,"t":"But as the assembly is subject to Christ, so let the wives also be to their own husbands in everything."},{"v":25,"t":"Husbands, love your wives, even as Christ also loved the assembly and gave himself up for her,"},{"v":26,"t":"that he might sanctify her, having cleansed her by the washing of water with the word,"},{"v":27,"t":"that he might present the assembly to himself gloriously, not having spot or wrinkle or any such thing, but that she should be holy and without defect."},{"v":28,"t":"Even so husbands also ought to love their own wives as their own bodies. He who loves his own wife loves himself."},{"v":29,"t":"For no man ever hated his own flesh, but nourishes and cherishes it, even as the Lord also does the assembly,"},{"v":30,"t":"because we are members of his body, of his flesh and bones."},{"v":31,"t":"“For this cause a man will leave his father and mother and will be joined to his wife. Then the two will become one flesh.”"},{"v":32,"t":"This mystery is great, but I speak concerning Christ and the assembly."},{"v":33,"t":"Nevertheless each of you must also love his own wife even as himself; and let the wife see that she respects her husband."}],"hr":[{"v":1,"t":"Budite dakle nasljedovatelji Božji kao djeca ljubljena"},{"v":2,"t":"i hodite u ljubavi kao što je i Krist ljubio vas i sebe predao za nas kao prinos i žrtvu Bogu na ugodan miris."},{"v":3,"t":"A bludnost i svaka nečistoća ili pohlepa neka se i ne spominje među vama, kako dolikuje svetima!"},{"v":4,"t":"Ni prostota, ni ludorija, ni dvosmislica, što se ne priliči, nego radije zahvaljivanje!"},{"v":5,"t":"Jer dobro znajte ovo: nijedan bludnik, ili bestidnik, ili pohlepnik - taj idolopoklonik - nema baštine u kraljevstvu Kristovu i Božjemu."},{"v":6,"t":"Nitko neka vas ispraznim riječima ne zavarava: zbog toga dolazi gnjev Božji na sinove neposlušne."},{"v":7,"t":"Nemajte dakle ništa s njima!"},{"v":8,"t":"Da, nekoć bijaste tama, a sada ste svjetlost u Gospodinu: kao djeca svjetlosti hodite -"},{"v":9,"t":"plod je svjetlosti svaka dobrota, pravednost i istina -"},{"v":10,"t":"i odlučite se za ono što je milo Gospodinu."},{"v":11,"t":"A nemajte udjela u jalovim djelima tame, nego ih dapače raskrinkavajte,"},{"v":12,"t":"jer što potajno čine, sramota je i govoriti."},{"v":13,"t":"A sve što se raskrinka, pod svjetlošću postaje sjajno; što je pak sjajno, svjetlost je."},{"v":14,"t":"Zato veli: “Probudi se, ti što spavaš, ustani od mrtvih i zasvijetljet će ti Krist.”"},{"v":15,"t":"Razmotrite dakle pomno kako živite! Ne kao ludi, nego kao mudri!"},{"v":16,"t":"Iskupljujte vrijeme jer dani su zli!"},{"v":17,"t":"Zato ne budite nerazumni, nego shvatite što je volja Gospodnja!"},{"v":18,"t":"I ne opijajte se vinom u kojem je razuzdanost, nego - punite se Duhom!"},{"v":19,"t":"Razgovarajte među sobom psalmima, hvalospjevima i duhovnim pjesmama! Pjevajte i slavite Gospodina u svom srcu!"},{"v":20,"t":"Svagda i za sve zahvaljujte Bogu i Ocu u imenu Gospodina našega Isusa Krista!"},{"v":21,"t":"Podložni budite jedni drugima u strahu Kristovu!"},{"v":22,"t":"Žene svojim muževima kao Gospodinu!"},{"v":23,"t":"Jer muž je glava žene kao i Krist Glava Crkve - On, Spasitelj Tijela."},{"v":24,"t":"Pa kao što se Crkva podlaže Kristu, tako i žene muževima u svemu!"},{"v":25,"t":"Muževi, ljubite svoje žene kao što je Krist ljubio Crkvu te sebe predao za nju"},{"v":26,"t":"da je posveti, očistivši je kupelji vode uz riječ"},{"v":27,"t":"te sebi predvede Crkvu slavnu, bez ljage i nabora ili čega takva, nego da bude sveta i bez mane."},{"v":28,"t":"Tako treba da i muževi ljube svoje žene kao svoja tijela. Tko ljubi svoju ženu, sebe ljubi."},{"v":29,"t":"Ta nitko nikada ne mrzi svoga tijela, nego ga hrani i njeguje kao i Krist Crkvu."},{"v":30,"t":"Doista, mi smo udovi njegova Tijela!"},{"v":31,"t":"Stoga će čovjek ostaviti oca i majku da prione uza svoju ženu; dvoje njih bit će jedno tijelo."},{"v":32,"t":"Otajstvo je to veliko! Ja smjeram na Krista i na Crkvu."},{"v":33,"t":"Dakle, neka svaki od vas ljubi svoju ženu kao samog sebe, a žena neka poštuje svog muža."}]},"6":{"fa":[{"v":1,"t":"ای فرزندان، والدین خود را در خداونداطاعت نمایید، زیرا که این انصاف است."},{"v":2,"t":"«پدر و مادر خود را احترام نما» که این حکم اول با وعده است."},{"v":3,"t":"«تا تو را عافیت باشد و عمر درازبر زمین کنی.»"},{"v":4,"t":"و‌ای پدران، فرزندان خود را به خشم میاورید بلکه ایشان را به تادیب و نصیحت خداوند تربیت نمایید."},{"v":5,"t":"‌ای غلامان، آقایان بشری خود را چون مسیح با ترس و لرز با ساده دلی اطاعت کنید."},{"v":6,"t":"نه به خدمت حضور مثل طالبان رضامندی انسان، بلکه چون غلامان مسیح که اراده خدا را از دل به عمل می‌آورند،"},{"v":7,"t":"و به نیت خالص خداوند رابندگی می‌کنند نه انسان را،"},{"v":8,"t":"و می‌دانند هرکس که عمل نیکو کند، مکافات آن را از خداوند خواهدیافت، خواه غلام و خواه آزاد."},{"v":9,"t":"و‌ای آقایان، باایشان به همین نسق رفتار نمایید و از تهدید کردن احتراز کنید، چونکه می‌دانید که خود شما را هم آقایی هست در آسمان و او را نظر به ظاهر نیست."},{"v":10,"t":"خلاصه‌ای برادران من، در خداوند و درتوانایی قوت او زورآور شوید."},{"v":11,"t":"اسلحه تمام خدا را بپوشید تا بتوانید با مکرهای ابلیس مقاومت کنید."},{"v":12,"t":"زیرا که ما را کشتی گرفتن با خون و جسم نیست بلکه با ریاستها و قدرتها وجهان داران این ظلمت و با فوجهای روحانی شرارت در جایهای آسمانی."},{"v":13,"t":"لهذا اسلحه تام خدا را بردارید تا بتوانید در روز شریر مقاومت کنید و همه کار را به‌جا آورده، بایستید."},{"v":14,"t":"پس کمر خود را به راستی بسته و جوشن عدالت رادربر کرده، بایستید."},{"v":15,"t":"و نعلین استعداد انجیل سلامتی را در پا کنید."},{"v":16,"t":"و بر روی این همه سپرایمان را بکشید که به آن بتوانید تمامی تیرهای آتشین شریر را خاموش کنید."},{"v":17,"t":"و خود نجات وشمشیر روح را که کلام خداست بردارید."},{"v":18,"t":"و بادعا والتماس تمام در هر وقت در روح دعا کنید وبرای همین به اصرار و التماس تمام بجهت همه مقدسین بیدار باشید."},{"v":19,"t":"و برای من نیز تا کلام به من عطا شود تا باگشادگی زبان سر انجیل را به دلیری اعلام نمایم،"},{"v":20,"t":"که برای آن در زنجیرها ایلچیگری می‌کنم تادر آن به دلیری سخن گویم، بطوری که می‌بایدگفت."},{"v":21,"t":"اما تا شما هم از احوال من و از آنچه می‌کنم مطلع شوید، تیخیکس که برادر عزیز و خادم امین در خداوند است، شما را از هرچیز خواهدآگاهانید،"},{"v":22,"t":"که او را بجهت همین به نزد شمافرستادم تا از احوال ما آگاه باشید و او دلهای شمارا تسلی بخشد."},{"v":23,"t":"برادران را سلام و محبت باایمان از جانب خدای پدر و عیسی مسیح خداوند باد."},{"v":24,"t":"با همه کسانی که به مسیح عیسی خداوند محبت در بی‌فسادی دارند، فیض باد. آمین."}],"en":[{"v":1,"t":"Children, obey your parents in the Lord, for this is right."},{"v":2,"t":"“Honor your father and mother,” which is the first commandment with a promise:"},{"v":3,"t":"“that it may be well with you, and you may live long on the earth.”"},{"v":4,"t":"You fathers, don’t provoke your children to wrath, but nurture them in the discipline and instruction of the Lord."},{"v":5,"t":"Servants, be obedient to those who according to the flesh are your masters, with fear and trembling, in singleness of your heart, as to Christ,"},{"v":6,"t":"not in the way of service only when eyes are on you, as men pleasers, but as servants of Christ, doing the will of God from the heart,"},{"v":7,"t":"with good will doing service as to the Lord and not to men,"},{"v":8,"t":"knowing that whatever good thing each one does, he will receive the same good again from the Lord, whether he is bound or free."},{"v":9,"t":"You masters, do the same things to them, and give up threatening, knowing that he who is both their Master and yours is in heaven, and there is no partiality with him."},{"v":10,"t":"Finally, be strong in the Lord and in the strength of his might."},{"v":11,"t":"Put on the whole armor of God, that you may be able to stand against the wiles of the devil."},{"v":12,"t":"For our wrestling is not against flesh and blood, but against the principalities, against the powers, against the world’s rulers of the darkness of this age, and against the spiritual forces of wickedness in the heavenly places."},{"v":13,"t":"Therefore put on the whole armor of God, that you may be able to withstand in the evil day, and having done all, to stand."},{"v":14,"t":"Stand therefore, having the utility belt of truth buckled around your waist, and having put on the breastplate of righteousness,"},{"v":15,"t":"and having fitted your feet with the preparation of the Good News of peace,"},{"v":16,"t":"above all, taking up the shield of faith, with which you will be able to quench all the fiery darts of the evil one."},{"v":17,"t":"And take the helmet of salvation, and the sword of the Spirit, which is the word of God;"},{"v":18,"t":"with all prayer and requests, praying at all times in the Spirit, and being watchful to this end in all perseverance and requests for all the saints."},{"v":19,"t":"Pray for me, that utterance may be given to me in opening my mouth, to make known with boldness the mystery of the Good News,"},{"v":20,"t":"for which I am an ambassador in chains; that in it I may speak boldly, as I ought to speak."},{"v":21,"t":"But that you also may know my affairs, how I am doing, Tychicus, the beloved brother and faithful servant in the Lord, will make known to you all things."},{"v":22,"t":"I have sent him to you for this very purpose, that you may know our state and that he may comfort your hearts."},{"v":23,"t":"Peace be to the brothers, and love with faith, from God the Father and the Lord Jesus Christ."},{"v":24,"t":"Grace be with all those who love our Lord Jesus Christ with incorruptible love. Amen."}],"hr":[{"v":1,"t":"Djeco, slušajte svoje roditelje u Gospodinu jer to je pravedno."},{"v":2,"t":"Poštuj oca svoga i majku - to je prva zapovijed s obećanjem:"},{"v":3,"t":"da ti dobro bude i da dugo živiš na zemlji."},{"v":4,"t":"A vi, očevi, ne srdite djece svoje, nego ih odgajajte stegom i urazumljivanjem Gospodnjim!"},{"v":5,"t":"Robovi, slušajte svoje zemaljske gospodare kao Krista - sa strahom i trepetom, u jednostavnosti srca."},{"v":6,"t":"Ne naoko, kao oni koji se ulaguju ljudima, nego kao sluge Kristove koje zdušno vrše volju Božju;"},{"v":7,"t":"dragovoljno služe - kao Gospodinu, a ne ljudima,"},{"v":8,"t":"znajući da će svatko, bio on rob ili slobodnjak, učini li što dobro, za to dobiti plaću od Gospodina."},{"v":9,"t":"I vi, gospodari, isto se tako vladajte prema njima: kanite se prijetnje, znajući da je i njihov i vaš Gospodar na nebesima i da u njega nema pristranosti."},{"v":10,"t":"Ubuduće jačajte se u Gospodinu i u silnoj snazi njegovoj."},{"v":11,"t":"Obucite svu opremu Božju da se mognete oduprijeti lukavstvima đavlovim."},{"v":12,"t":"Jer nije nam se boriti protiv krvi i mesa, nego protiv Vrhovništava, protiv Vlasti, protiv upravljača ovoga mračnoga svijeta, protiv zlih duhova po nebesima."},{"v":13,"t":"Zbog toga posegnite za svom opremom Božjom da uzmognete odoljeti u dan zli i održati se kada sve nadvladate."},{"v":14,"t":"Držite se dakle! Opašite bedra istinom, obucite oklop pravednosti,"},{"v":15,"t":"potpašite noge spremnošću za evanđelje mira!"},{"v":16,"t":"U svemu imajte uza se štit vjere: njime ćete moći ugasiti ognjene strijele Zloga."},{"v":17,"t":"Uzmite i kacigu spasenja i mač Duha, to jest Riječ Božju."},{"v":18,"t":"Svakovrsnom se molitvom i prošnjom u svakoj prigodi u Duhu molite. Poradi toga i bdijte sa svom ustrajnošću i molitvom za sve svete,"},{"v":19,"t":"i za me, da mi se otvore usta i dade riječ hrabro obznaniti otajstvo evanđelja"},{"v":20,"t":"kojeg sam poslanik u okovima, da se ohrabrim o njemu kako treba govoriti."},{"v":21,"t":"A da i vi znate što je sa mnom, kako mi je, o svemu će vas obavijestiti Tihik, ljubljeni brat i vjerni poslužitelj u Gospodinu."},{"v":22,"t":"Njega šaljem k vama baš zato da znate kako smo i da ohrabri srca vaša."},{"v":23,"t":"Mir braći i ljubav, s vjerom, od Boga Oca i Gospodina Isusa Krista!"},{"v":24,"t":"Milost sa svima koji ljube Gospodina našega Isusa Krista - u neraspadljivosti."}]}},"PHP":{"1":{"fa":[{"v":1,"t":"پولس و تیموتاوس، غلامان عیسی مسیح، به همه مقدسین در مسیح عیسی که درفیلپی می‌باشند با اسقفان و شماسان."},{"v":2,"t":"فیض و سلامتی از جانب پدر ما خدا وعیسی مسیح خداوند بر شما باد."},{"v":3,"t":"در تمامی یادگاری شما خدای خود را شکرمی گذارم،"},{"v":4,"t":"و پیوسته در هر دعای خود برای جمیع شما به خوشی دعا می‌کنم،"},{"v":5,"t":"به‌سبب مشارکت شما برای انجیل از روز اول تا به حال."},{"v":6,"t":"چونکه به این اعتماد دارم که او که عمل نیکو رادر شما شروع کرد، آن را تا روز عیسی مسیح به‌کمال خواهد رسانید."},{"v":7,"t":"چنانکه مرا سزاوار است که درباره همه شما همین فکر کنم زیرا که شما رادر دل خود می‌دارم که در زنجیرهای من و درحجت و اثبات انجیل همه شما با من شریک دراین نعمت هستید."},{"v":8,"t":"زیرا خدا مرا شاهد است که چقدر در احشای عیسی مسیح، مشتاق همه شماهستم."},{"v":9,"t":"و برای این دعا می‌کنم تا محبت شما درمعرفت و کمال فهم بسیار افزونتر شود."},{"v":10,"t":"تاچیزهای بهتر را برگزینید و در روز مسیح بی‌غش و بی‌لغزش باشید،"},{"v":11,"t":"و پر شوید از میوه عدالت که بوسیله عیسی مسیح برای تمجید و حمدخداست."},{"v":12,"t":"اما‌ای برادران، می‌خواهم شما بدانید که آنچه بر من واقع گشت، برعکس به ترقی انجیل انجامید،"},{"v":13,"t":"بحدی که زنجیرهای من آشکارا شددر مسیح در تمام فوج خاص و به همه دیگران."},{"v":14,"t":"و اکثر از برادران در خداوند از زنجیرهای من اعتماد به هم رسانیده، بیشتر جرات می‌کنند که کلام خدا را بی‌ترس بگویند."},{"v":15,"t":"اما بعضی ازحسد و نزاع به مسیح موعظه می‌کنند، ولی بعضی هم از خشنودی."},{"v":16,"t":"اما آنان از تعصب نه ازاخلاص به مسیح اعلام می‌کنند و گمان می‌برندکه به زنجیرهای من زحمت می‌افزایند."},{"v":17,"t":"ولی اینان از راه محبت، چونکه می‌دانند که من بجهت حمایت انجیل معین شده‌ام."},{"v":18,"t":"پس چه؟ جز اینکه به هر صورت، خواه به بهانه و خواه به راستی، به مسیح موعظه می‌شود واز این شادمانم بلکه شادی هم خواهم کرد،"},{"v":19,"t":"زیرا می‌دانم که به نجات من خواهد انجامیدبوسیله دعای شما و تایید روح عیسی مسیح،"},{"v":20,"t":"برحسب انتظار و امید من که در هیچ‌چیزخجالت نخواهم کشید، بلکه در کمال دلیری، چنانکه همیشه، الان نیز مسیح در بدن من جلال خواهد یافت، خواه در حیات و خواه در موت."},{"v":21,"t":"زیرا که مرا زیستن مسیح است و مردن نفع."},{"v":22,"t":"و لیکن اگر زیستن در جسم، همان ثمر کار من است، پس نمی دانم کدام را اختیار کنم."},{"v":23,"t":"زیرادر میان این دو سخت گرفتار هستم، چونکه خواهش دارم که رحلت کنم و با مسیح باشم، زیرااین بسیار بهتر است."},{"v":24,"t":"لیکن در جسم ماندن برای شما لازمتر است."},{"v":25,"t":"و چون این اعتماد را دارم، می‌دانم که خواهم ماند و نزد همه شما توقف خواهم نمود بجهت ترقی و خوشی ایمان شما،"},{"v":26,"t":"تا فخر شما در مسیح عیسی در من افزوده شودبوسیله آمدن من بار دیگر نزد شما."},{"v":27,"t":"باری بطور شایسته انجیل مسیح رفتارنمایید تا خواه آیم و شما را بینم و خواه غایب باشم، احوال شما را بشنوم که به یک روح برقرارید و به یک نفس برای ایمان انجیل مجاهده می‌کنید."},{"v":28,"t":"و در هیچ امری از دشمنان ترسان نیستید که همین برای ایشان دلیل هلاکت است، اما شما را دلیل نجات و این از خداست."},{"v":29,"t":"زیراکه به شما عطا شد به‌خاطر مسیح نه فقط ایمان آوردن به او بلکه زحمت کشیدن هم برای او. وشما را همان مجاهده است که در من دیدید و الان هم می‌شنوید که در من است."}],"en":[{"v":1,"t":"Paul and Timothy, servants of Jesus Christ, to all the saints in Christ Jesus who are at Philippi, with the overseers and servants:"},{"v":2,"t":"Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":3,"t":"I thank my God whenever I remember you,"},{"v":4,"t":"always in every request of mine on behalf of you all, making my requests with joy,"},{"v":5,"t":"for your partnership in furtherance of the Good News from the first day until now;"},{"v":6,"t":"being confident of this very thing, that he who began a good work in you will complete it until the day of Jesus Christ."},{"v":7,"t":"It is even right for me to think this way on behalf of all of you, because I have you in my heart, because both in my bonds and in the defense and confirmation of the Good News, you all are partakers with me of grace."},{"v":8,"t":"For God is my witness, how I long after all of you in the tender mercies of Christ Jesus."},{"v":9,"t":"This I pray, that your love may abound yet more and more in knowledge and all discernment,"},{"v":10,"t":"so that you may approve the things that are excellent, that you may be sincere and without offense to the day of Christ,"},{"v":11,"t":"being filled with the fruits of righteousness which are through Jesus Christ, to the glory and praise of God."},{"v":12,"t":"Now I desire to have you know, brothers, that the things which happened to me have turned out rather to the progress of the Good News,"},{"v":13,"t":"so that it became evident to the whole palace guard, and to all the rest, that my bonds are in Christ,"},{"v":14,"t":"and that most of the brothers in the Lord, being confident through my bonds, are more abundantly bold to speak the word of God without fear."},{"v":15,"t":"Some indeed preach Christ even out of envy and strife, and some also out of good will."},{"v":16,"t":"The former insincerely preach Christ from selfish ambition, thinking that they add affliction to my chains;"},{"v":17,"t":"but the latter out of love, knowing that I am appointed for the defense of the Good News."},{"v":18,"t":"What does it matter? Only that in every way, whether in pretense or in truth, Christ is proclaimed. I rejoice in this, yes, and will rejoice."},{"v":19,"t":"For I know that this will turn out to my salvation through your prayers and the supply of the Spirit of Jesus Christ,"},{"v":20,"t":"according to my earnest expectation and hope, that I will in no way be disappointed, but with all boldness, as always, now also Christ will be magnified in my body, whether by life or by death."},{"v":21,"t":"For to me to live is Christ, and to die is gain."},{"v":22,"t":"But if I live on in the flesh, this will bring fruit from my work; yet I don’t know what I will choose."},{"v":23,"t":"But I am hard pressed between the two, having the desire to depart and be with Christ, which is far better."},{"v":24,"t":"Yet to remain in the flesh is more needful for your sake."},{"v":25,"t":"Having this confidence, I know that I will remain, yes, and remain with you all for your progress and joy in the faith,"},{"v":26,"t":"that your boasting may abound in Christ Jesus in me through my presence with you again."},{"v":27,"t":"Only let your way of life be worthy of the Good News of Christ, that whether I come and see you or am absent, I may hear of your state, that you stand firm in one spirit, with one soul striving for the faith of the Good News;"},{"v":28,"t":"and in nothing frightened by the adversaries, which is for them a proof of destruction, but to you of salvation, and that from God."},{"v":29,"t":"Because it has been granted to you on behalf of Christ, not only to believe in him, but also to suffer on his behalf,"},{"v":30,"t":"having the same conflict which you saw in me and now hear is in me."}],"hr":[{"v":1,"t":"Pavao i Timotej, sluge Krista Isusa, svima svetima u Kristu Isusu koji su u Filipima, s nadglednicima i poslužiteljima."},{"v":2,"t":"Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista!"},{"v":3,"t":"Zahvaljujem Bogu svomu kad vas se god sjetim."},{"v":4,"t":"Uvijek se u svakoj svojoj molitvi za vas s radošću molim"},{"v":5,"t":"zbog vašeg udjela u evanđelju od onoga prvog dana sve do sada -"},{"v":6,"t":"uvjeren u ovo: Onaj koji otpoče u vama dobro djelo, dovršit će ga do Dana Krista Isusa."},{"v":7,"t":"I pravo je da tako osjećam o svima vama! Ta ja vas nosim u srcu jer u okovima mojim i u obrani i utvrđivanju evanđelja svi ste vi suzajedničari moje milosti."},{"v":8,"t":"Bog mi je doista svjedok koliko žudim za svima vama srcem Isusa Krista!"},{"v":9,"t":"I molim za ovo: da ljubav vaša sve više i više raste u spoznanju i potpunu pronicanju"},{"v":10,"t":"te mognete prosuditi što je najbolje da budete čisti i besprijekorni za Dan Kristov,"},{"v":11,"t":"puni ploda pravednosti po Isusu Kristu - na slavu i hvalu Božju."},{"v":12,"t":"A hoću da znate, braćo: ovaj se moj udes pače okrenuo u napredovanje evanđelja"},{"v":13,"t":"tako da se moji okovi u Kristu razglasiše u svem pretoriju i među svima drugima,"},{"v":14,"t":"a većina braće u Gospodinu, ohrabrena mojim okovima, još se više usuđuje neustrašivo zboriti Riječ."},{"v":15,"t":"Neki, istina, propovijedaju Krista iz zavisti i nadmetanja, a neki iz dobre volje:"},{"v":16,"t":"ovi iz ljubavi jer znaju da sam ovdje za obranu evanđelja;"},{"v":17,"t":"oni pak Krista navješćuju iz suparništva, neiskreno - misleći da će tako otežati nevolju mojih okova."},{"v":18,"t":"Pa što onda? Samo se na svaki način, bilo himbeno, bilo istinito, Krist navješćuje. I tome se radujem, a i radovat ću se."},{"v":19,"t":"Jer znadem: po vašoj molitvi i pomoći Duha Isusa Krista to će mi biti na spasenje,"},{"v":20,"t":"kako željno i očekujem i nadam se da se ni zbog čega neću smesti, nego da će se mojom posvemašnjom odvažnošću - kako uvijek tako i sada - Krist uzveličati u mome tijelu, bilo životom, bilo smrću."},{"v":21,"t":"Ta meni je živjeti Krist, a umrijeti dobitak!"},{"v":22,"t":"A ako mi živjeti u tijelu omogućuje plodno djelovanje, što da odaberem? Ne znam!"},{"v":23,"t":"Pritiješnjen sam od ovoga dvoga: želja mi je otići i s Kristom biti jer to je mnogo, mnogo bolje;"},{"v":24,"t":"ali ostati u tijelu potrebnije je poradi vas."},{"v":25,"t":"U to uvjeren, znam da ću ostati i biti uz vas sve, za vaš napredak i na radost vjere,"},{"v":26,"t":"da ponos vaš mnome poraste u Kristu Isusu kad opet dođem k vama."},{"v":27,"t":"Samo se ponašajte dostojno evanđelja Kristova, pa - došao ja i vidio vas ili nenazočan slušao što je s vama - da mogu utvrditi kako ste postojani u jednome duhu i jednodušno se zajednički borite za evanđeosku vjeru"},{"v":28,"t":"ne plašeći se ni u čemu protivnika. To je njima najava njihove propasti, a vašega spasenja, i to od Boga."},{"v":29,"t":"Jer vama je dana milost: “za Krista”, ne samo u njega vjerovati nego za njega i trpjeti,"},{"v":30,"t":"isti boj bijući koji na meni vidjeste i sada o meni čujete."}]},"2":{"fa":[{"v":1,"t":"بنابراین اگر نصیحتی در مسیح، یا تسلی محبت، یا شراکت در روح، یا شفقت ورحمت هست،"},{"v":2,"t":"پس خوشی مرا کامل گردانید تابا هم یک فکر کنید و همان محبت نموده، یک دل بشوید و یک فکر داشته باشید."},{"v":3,"t":"و هیچ‌چیز را ازراه تعصب و عجب مکنید، بلکه با فروتنی دیگران را از خود بهتر بدانید."},{"v":4,"t":"و هریک از شما ملاحظه کارهای خود را نکند، بلکه هرکدام کارهای دیگران را نیز."},{"v":5,"t":"پس همین فکر در شما باشد که در مسیح عیسی نیز بود"},{"v":6,"t":"که چون در صورت خدا بود، باخدا برابر بودن را غنیمت نشمرد،"},{"v":7,"t":"لیکن خود راخالی کرده، صورت غلام را پذیرفت و درشباهت مردمان شد؛"},{"v":8,"t":"و چون در شکل انسان یافت شد، خویشتن را فروتن ساخت و تا به موت بلکه تا به موت صلیب مطیع گردید."},{"v":9,"t":"از این جهت خدا نیز او را بغایت سرافراز نمود و نامی را که فوق از جمیع نامها است، بدو بخشید."},{"v":10,"t":"تا به نام عیسی هر زانویی از آنچه در آسمان و بر زمین وزیر زمین است خم شود،"},{"v":11,"t":"و هر زبانی اقرار کندکه عیسی مسیح، خداوند است برای تمجیدخدای پدر."},{"v":12,"t":"پس‌ای عزیزان من چنانکه همیشه مطیع می‌بودید، نه در حضور من فقط بلکه بسیار زیادترالان وقتی که غایبم، نجات خود را به ترس و لرزبعمل آورید."},{"v":13,"t":"زیرا خداست که در شمابرحسب رضامندی خود، هم اراده و هم فعل رابعمل ایجاد می‌کند."},{"v":14,"t":"و هرکاری را بدون همهمه و مجادله بکنید،"},{"v":15,"t":"تا بی‌عیب و ساده دل و فرزندان خدا بی‌ملامت باشید، در میان قومی کج رو و گردنکش که در آن میان چون نیرها درجهان می‌درخشید،"},{"v":16,"t":"و کلام حیات رابرمی افرازید، بجهت فخر من در روز مسیح تاآنکه عبث ندویده و عبث زحمت نکشیده باشم."},{"v":17,"t":"بلکه هرگاه بر قربانی و خدمت ایمان شماریخته شوم، شادمان هستم و با همه شما شادی می‌کنم."},{"v":18,"t":"و همچنین شما نیز شادمان هستید و بامن شادی می‌کنید."},{"v":19,"t":"و در عیسی خداوند امیدوارم که تیموتاوس را به زودی نزد شما بفرستم تامن نیز ازاحوال شما مطلع شده، تازه روح گردم."},{"v":20,"t":"زیراکسی دیگر را همدل ندارم که به اخلاص درباره شما اندیشد."},{"v":21,"t":"زانرو که همه نفع خود رامی طلبند، نه امور عیسی مسیح را."},{"v":22,"t":"اما دلیل اورا می‌دانید، زیرا چنانکه فرزند پدر را خدمت می‌کند، او با من برای انجیل خدمت کرده است."},{"v":23,"t":"پس امیدوارم که چون دیدم کار من چطورمی شود، او را بی‌درنگ بفرستم."},{"v":24,"t":"اما در خداونداعتماد دارم که خود هم به زودی بیایم."},{"v":25,"t":"ولی لازم دانستم که اپفردتس را به سوی شما روانه نمایم که مرا برادر و همکار و همجنگ می‌باشد، اما شما را رسول و خادم حاجت من."},{"v":26,"t":"زیرا که مشتاق همه شما بود و غمگین شد ازاینکه شنیده بودید که او بیمار شده بود."},{"v":27,"t":"وفی الواقع بیمار و مشرف بر موت بود، لیکن خدا بروی ترحم فرمود و نه بر او فقط بلکه بر من نیز تامرا غمی بر غم نباشد."},{"v":28,"t":"پس به سعی بیشتر او راروانه نمودم تا از دیدنش باز شاد شوید و حزن من کمتر شود."},{"v":29,"t":"پس او را در خداوند با کمال خوشی بپذیرید و چنین کسان را محترم بدارید،"},{"v":30,"t":"زیرا در کار مسیح مشرف بر موت شد و جان خود را به خطر انداخت تا نقص خدمت شما را برای من به‌کمال رساند."}],"en":[{"v":1,"t":"If therefore there is any exhortation in Christ, if any consolation of love, if any fellowship of the Spirit, if any tender mercies and compassion,"},{"v":2,"t":"make my joy full by being like-minded, having the same love, being of one accord, of one mind;"},{"v":3,"t":"doing nothing through rivalry or through conceit, but in humility, each counting others better than himself;"},{"v":4,"t":"each of you not just looking to his own things, but each of you also to the things of others."},{"v":5,"t":"Have this in your mind, which was also in Christ Jesus,"},{"v":6,"t":"who, existing in the form of God, didn’t consider equality with God a thing to be grasped,"},{"v":7,"t":"but emptied himself, taking the form of a servant, being made in the likeness of men."},{"v":8,"t":"And being found in human form, he humbled himself, becoming obedient to the point of death, yes, the death of the cross."},{"v":9,"t":"Therefore God also highly exalted him, and gave to him the name which is above every name,"},{"v":10,"t":"that at the name of Jesus every knee should bow, of those in heaven, those on earth, and those under the earth,"},{"v":11,"t":"and that every tongue should confess that Jesus Christ is Lord, to the glory of God the Father."},{"v":12,"t":"So then, my beloved, even as you have always obeyed, not only in my presence, but now much more in my absence, work out your own salvation with fear and trembling."},{"v":13,"t":"For it is God who works in you both to will and to work for his good pleasure."},{"v":14,"t":"Do all things without complaining and arguing,"},{"v":15,"t":"that you may become blameless and harmless, children of God without defect in the middle of a crooked and perverse generation, among whom you are seen as lights in the world,"},{"v":16,"t":"holding up the word of life, that I may have something to boast in the day of Christ that I didn’t run in vain nor labor in vain."},{"v":17,"t":"Yes, and if I am poured out on the sacrifice and service of your faith, I am glad and rejoice with you all."},{"v":18,"t":"In the same way, you also should be glad and rejoice with me."},{"v":19,"t":"But I hope in the Lord Jesus to send Timothy to you soon, that I also may be cheered up when I know how you are doing."},{"v":20,"t":"For I have no one else like-minded, who will truly care about you."},{"v":21,"t":"For they all seek their own, not the things of Jesus Christ."},{"v":22,"t":"But you know that he has proved himself. As a child serves a father, so he served with me in furtherance of the Good News."},{"v":23,"t":"Therefore I hope to send him at once, as soon as I see how it will go with me."},{"v":24,"t":"But I trust in the Lord that I myself also will come shortly."},{"v":25,"t":"But I thought it necessary to send to you Epaphroditus, my brother, fellow worker, fellow soldier, and your apostle and servant of my need,"},{"v":26,"t":"since he longed for you all, and was very troubled because you had heard that he was sick."},{"v":27,"t":"For indeed he was sick nearly to death, but God had mercy on him, and not on him only, but on me also, that I might not have sorrow on sorrow."},{"v":28,"t":"I have sent him therefore the more diligently, that when you see him again, you may rejoice, and that I may be the less sorrowful."},{"v":29,"t":"Receive him therefore in the Lord with all joy, and hold such people in honor,"},{"v":30,"t":"because for the work of Christ he came near to death, risking his life to supply that which was lacking in your service toward me."}],"hr":[{"v":1,"t":"Ima li dakle u Kristu kakve utjehe, ima li kakva ljubazna bodrenja, ima li kakva zajedništva Duha, ima li kakva srca i samilosti,"},{"v":2,"t":"ispunite me radošću: složni budite, istu ljubav njegujte, jednodušni, jedne misli budite;"},{"v":3,"t":"nikakvo suparništvo ni umišljenost, nego - u poniznosti jedni druge smatrajte višima od sebe;"},{"v":4,"t":"ne starajte se samo svaki za svoje, nego i za ono što se tiče drugih!"},{"v":5,"t":"Neka u vama bude isto mišljenje kao i u Kristu Isusu:"},{"v":6,"t":"On, trajni lik Božji, nije se kao plijena držao svoje jednakosti s Bogom,"},{"v":7,"t":"nego sam sebe “oplijeni” uzevši lik sluge, postavši ljudima sličan; obličjem čovjeku nalik,"},{"v":8,"t":"ponizi sam sebe, poslušan do smrti, smrti na križu."},{"v":9,"t":"Zato Bog njega preuzvisi i darova mu ime, ime nad svakim imenom,"},{"v":10,"t":"da se na ime Isusovo prigne svako koljeno nebesnika, zemnika i podzemnika."},{"v":11,"t":"I svaki će jezik priznati: “Isus Krist jest Gospodin!” - na slavu Boga Oca."},{"v":12,"t":"Tako, ljubljeni moji, poslušni kako uvijek bijaste, ne samo kao ono za moje nazočnosti nego mnogo više sada, za moje nenazočnosti, sa strahom i trepetom radite oko svoga spasenja!"},{"v":13,"t":"Da, Bog u svojoj dobrohotnosti izvodi u vama i htjeti i djelovati."},{"v":14,"t":"Sve činite bez mrmljanja i oklijevanja"},{"v":15,"t":"da budete besprijekorni i čisti, djeca Božja neporočna posred poroda izopačena i lukava u kojem svijetlite kao svjetlila u svijetu"},{"v":16,"t":"držeći riječ Života meni na ponos za Dan Kristov, što nisam zaludu trčao niti se zaludu trudio."},{"v":17,"t":"Naprotiv, ako se ja i izlijevam za žrtvu i bogoslužje, za vjeru vašu, radostan sam i radujem se sa svima vama."},{"v":18,"t":"A tako i vi budite radosni i radujte se sa mnom."},{"v":19,"t":"Nadam se u Gospodinu Isusu da ću vam uskoro poslati Timoteja da mi odlane kad saznam što je s vama."},{"v":20,"t":"Nikoga doista nemam tako srodne duše tko bi se kao on svojski za vas pobrinuo"},{"v":21,"t":"jer svi traže svoje, a ne ono što je Isusa Krista."},{"v":22,"t":"A prokušanost vam je njegova poznata: kao dijete s ocem služio je sa mnom evanđelju."},{"v":23,"t":"Njega se dakle nadam poslati tek što razvidim što je sa mnom."},{"v":24,"t":"A uvjeren sam u Gospodinu da ću i sam uskoro doći."},{"v":25,"t":"Smatrao sam potrebnim poslati k vama Epafrodita, brata, suradnika i suborca moga kojega ste poslali da mi poslužuje u potrebi."},{"v":26,"t":"Jer je čeznuo za svima vama i bio zabrinut što ste saznali da je obolio."},{"v":27,"t":"I doista je gotovo na smrt bio obolio, ali Bog mu se smilovao, ne samo njemu nego i meni, da me ne zadesi žalost na žalost."},{"v":28,"t":"Brže ga dakle poslah da se, pošto ga vidite, opet obradujete, i ja da budem manje žalostan."},{"v":29,"t":"Primite ga dakle u Gospodinu sa svom radosti i poštujte takve"},{"v":30,"t":"jer se za djelo Kristovo smrti sasvim približio, životnoj se pogibli izložio da nadopuni ono u čemu me vi ne mogoste poslužiti."}]},"3":{"fa":[{"v":1,"t":"خلاصه‌ای برادران من، در خداوند خوش باشید. همان مطالب را به شما نوشتن بر من سنگین نیست و ایمنی شما است."},{"v":2,"t":"از سگهاباحذر باشید. از عاملان شریر احتراز نمایید. ازمقطوعان بپرهیزید."},{"v":3,"t":"زیرا مختونان ما هستیم که خدا را در روح عبادت می‌کنیم و به مسیح عیسی فخر می‌کنیم و بر جسم اعتماد نداریم."},{"v":4,"t":"هرچندمرا در جسم نیز اعتماد است. اگر کسی دیگرگمان برد که در جسم اعتماد دارد، من بیشتر."},{"v":5,"t":"روز هشتم مختون شده و از قبیله اسرائیل، ازسبط بنیامین، عبرانی از عبرانیان، از جهت شریعت فریسی،"},{"v":6,"t":"از جهت غیرت جفا کننده برکلیسا، از جهت عدالت شریعتی، بی‌عیب."},{"v":7,"t":"اما آنچه مرا سود می‌بود، آن را به‌خاطرمسیح زیان دانستم."},{"v":8,"t":"بلکه همه‌چیز را نیز به‌سبب فضیلت معرفت خداوند خود مسیح عیسی زیان می‌دانم که بخاطر او همه‌چیز را زیان کردم وفضله شمردم تا مسیح را دریابم."},{"v":9,"t":"و در وی یافت شوم نه با عدالت خود که شریعت است، بلکه با آن که بوسیله ایمان مسیح می‌شود، یعنی عدالتی که از خدا بر ایمان است."},{"v":10,"t":"و تا او را و قوت قیامت وی را و شراکت در رنجهای وی را بشناسم و باموت او مشابه گردم."},{"v":11,"t":"مگر به هر وجه به قیامت از مردگان برسم."},{"v":12,"t":"نه اینکه تا به حال به چنگ آورده یا تابحال کامل شده باشم، ولی در‌پی آن می‌کوشم بلکه شاید آن را بدست آورم که برای آن مسیح نیز مرا بدست آورد."},{"v":13,"t":"‌ای برادران، گمان نمی برم که من بدست آورده‌ام؛ لیکن یک چیز می‌کنم که آنچه در عقب است فراموش کرده و به سوی آنچه در‌پیش است، خویشتن را کشیده،"},{"v":14,"t":"در‌پی مقصدمی کوشم بجهت انعام دعوت بلند خدا که درمسیح عیسی است."},{"v":15,"t":"پس جمیع ما که کامل هستیم، این فکر داشته باشیم و اگر فی الجمله فکردیگر دارید، خدا این را هم بر شما کشف خواهدفرمود."},{"v":16,"t":"اما به هر مقامی که رسیده‌ایم، به همان قانون رفتار باید کرد."},{"v":17,"t":"‌ای برادران، با هم به من اقتدا نمایید وملاحظه کنید آنانی را که بحسب نمونه‌ای که در مادارید، رفتار می‌کنند."},{"v":18,"t":"زیرا که بسیاری رفتارمی نمایند که ذکر ایشان را بارها برای شما کرده‌ام و حال نیز با گریه می‌کنم که دشمنان صلیب مسیح می‌باشند،"},{"v":19,"t":"که انجام ایشان هلاکت است وخدای ایشان شکم ایشان و فخر ایشان در ننگ ایشان، و چیزهای دنیوی را اندیشه می‌کنند."},{"v":20,"t":"اما وطن ما در آسمان است که از آنجا نیزنجات‌دهنده یعنی عیسی مسیح خداوند را انتظارمی کشیم،"},{"v":21,"t":"که شکل جسد ذلیل ما را تبدیل خواهد نمود تا به صورت جسد مجید او مصورشود، برحسب عمل قوت خود که همه‌چیز رامطیع خود بگرداند."}],"en":[{"v":1,"t":"Finally, my brothers, rejoice in the Lord! To write the same things to you, to me indeed is not tiresome, but for you it is safe."},{"v":2,"t":"Beware of the dogs; beware of the evil workers; beware of the false circumcision."},{"v":3,"t":"For we are the circumcision, who worship God in the Spirit, and rejoice in Christ Jesus, and have no confidence in the flesh;"},{"v":4,"t":"though I myself might have confidence even in the flesh. If any other man thinks that he has confidence in the flesh, I yet more:"},{"v":5,"t":"circumcised the eighth day, of the stock of Israel, of the tribe of Benjamin, a Hebrew of Hebrews; concerning the law, a Pharisee;"},{"v":6,"t":"concerning zeal, persecuting the assembly; concerning the righteousness which is in the law, found blameless."},{"v":7,"t":"However, I consider those things that were gain to me as a loss for Christ."},{"v":8,"t":"Yes most certainly, and I count all things to be a loss for the excellency of the knowledge of Christ Jesus, my Lord, for whom I suffered the loss of all things, and count them nothing but refuse, that I may gain Christ"},{"v":9,"t":"and be found in him, not having a righteousness of my own, that which is of the law, but that which is through faith in Christ, the righteousness which is from God by faith,"},{"v":10,"t":"that I may know him and the power of his resurrection, and the fellowship of his sufferings, becoming conformed to his death,"},{"v":11,"t":"if by any means I may attain to the resurrection from the dead."},{"v":12,"t":"Not that I have already obtained, or am already made perfect; but I press on, that I may take hold of that for which also I was taken hold of by Christ Jesus."},{"v":13,"t":"Brothers, I don’t regard myself as yet having taken hold, but one thing I do: forgetting the things which are behind and stretching forward to the things which are before,"},{"v":14,"t":"I press on toward the goal for the prize of the high calling of God in Christ Jesus."},{"v":15,"t":"Let us therefore, as many as are perfect, think this way. If in anything you think otherwise, God will also reveal that to you."},{"v":16,"t":"Nevertheless, to the extent that we have already attained, let’s walk by the same rule. Let’s be of the same mind."},{"v":17,"t":"Brothers, be imitators together of me, and note those who walk this way, even as you have us for an example."},{"v":18,"t":"For many walk, of whom I told you often, and now tell you even weeping, as the enemies of the cross of Christ,"},{"v":19,"t":"whose end is destruction, whose god is the belly, and whose glory is in their shame, who think about earthly things."},{"v":20,"t":"For our citizenship is in heaven, from where we also wait for a Savior, the Lord Jesus Christ,"},{"v":21,"t":"who will change the body of our humiliation to be conformed to the body of his glory, according to the working by which he is able even to subject all things to himself."}],"hr":[{"v":1,"t":"Uostalom, braćo moja, radujte se u Gospodinu! Pisati vam jedno te isto meni nije dosadno, a za vas je sigurnije."},{"v":2,"t":"Čuvajte se tih pasa, čuvajte se tih opakih radnika, čuvajte se te osakaćenosti!"},{"v":3,"t":"Jer mi smo obrezanje, mi koji u Duhu Božjemu obavljamo bogoslužje i dičimo se Kristom Isusom, a ne pouzdajemo se u tijelo,"},{"v":4,"t":"iako bih se ja mogao pouzdati i u tijelo. Smatra li tko drugi da se može uzdati u tijelo, ja još više:"},{"v":5,"t":"obrezan osmog dana, od roda sam Izraelova, plemena Benjaminova, Hebrej od Hebreja; po Zakonu farizej,"},{"v":6,"t":"po revnosti progonitelj Crkve, po pravednosti zakonskoj besprijekoran."},{"v":7,"t":"Ali što mi god bijaše dobitak, to poradi Krista smatram gubitkom."},{"v":8,"t":"Štoviše, čak sve gubitkom smatram zbog onoga najizvrsnijeg, zbog spoznanja Isusa Krista, Gospodina mojega, radi kojega sve izgubih i otpadom smatram: da Krista steknem"},{"v":9,"t":"i u njemu se nađem - ne svojom pravednošću, onom od Zakona, nego pravednošću po vjeri u Krista, onom od Boga, na vjeri utemeljenoj -"},{"v":10,"t":"da upoznam njega i snagu uskrsnuća njegova i zajedništvo u patnjama njegovim,"},{"v":11,"t":"ne bih li kako, suobličen smrti njegovoj, prispio k uskrsnuću od mrtvih."},{"v":12,"t":"Ne kao da sam već postigao ili dopro do savršenstva, nego - hitim ne bih li kako dohvatio jer sam i zahvaćen od Krista."},{"v":13,"t":"Braćo, ja nipošto ne smatram da sam već dohvatio. Jedno samo: što je za mnom, zaboravljam, za onim što je preda mnom, prežem,"},{"v":14,"t":"k cilju hitim, k nagradi višnjeg poziva Božjeg u Kristu Isusu."},{"v":15,"t":"Koji smo god zreli, ovako mislimo! I ako što drukčije mislite, Bog će vam ovako objaviti."},{"v":16,"t":"Samo, držimo se onoga do čega smo stigli!"},{"v":17,"t":"Braćo! Nasljedovatelji moji budite i promatrajte one koji žive po uzoru koji imate u nama."},{"v":18,"t":"Jer često sam vam govorio, a sada i plačući govorim: mnogi žive kao neprijatelji križa Kristova."},{"v":19,"t":"Svršetak im je propast, bog im je trbuh, slava u sramoti - jer misle na zemaljsko."},{"v":20,"t":"Naša je pak domovina na nebesima, odakle iščekujemo Spasitelja, Gospodina našega Isusa Krista:"},{"v":21,"t":"snagom kojom ima moć sve sebi podložiti on će preobraziti ovo naše bijedno tijelo i suobličiti ga tijelu svomu slavnomu."}]},"4":{"fa":[{"v":1,"t":"بنابراین، ای بردران عزیز و مورد اشتیاق من و شادی و تاج من، به همینطور در خداونداستوار باشید‌ای عزیزان."},{"v":2,"t":"از افودیه استدعا دارم و به سنتیخی التماس دارم که در خداوند یک رای باشند."},{"v":3,"t":"و از تو نیز‌ای همقطار خالص خواهش می‌کنم که ایشان را امداد کنی، زیرا درجهاد انجیل با من شریک می‌بودند با اکلیمنتس نیز و سایر همکاران من که نام ایشان در دفترحیات‌است."},{"v":4,"t":"در خداوند دائم شاد باشید. و باز می‌گویم شاد باشید."},{"v":5,"t":"اعتدال شما بر جمیع مردم معروف بشود. خداوند نزدیک است."},{"v":6,"t":"برای هیچ‌چیزاندیشه مکنید، بلکه در هرچیز با صلات و دعا باشکرگزاری مسولات خود را به خدا عرض کنید."},{"v":7,"t":"و سلامتی خدا که فوق از تمامی عقل است، دلها و ذهنهای شما را در مسیح عیسی نگاه خواهد داشت."},{"v":8,"t":"خلاصه‌ای برادران، هرچه راست باشد وهرچه مجید و هرچه عادل و هرچه پاک و هرچه جمیل و هرچه نیک نام است و هر فضیلت و هرمدحی که بوده باشد، در آنها تفکر کنید."},{"v":9,"t":"و آنچه در من آموخته و پذیرفته و شنیده و دیده‌اید، آنهارا بعمل آرید، و خدای سلامتی با شما خواهدبود."},{"v":10,"t":"و در خداوند بسیار شاد گردیدم که الان آخر، فکر شما برای من شکوفه آورد و در این نیزتفکر می‌کردید، لیکن فرصت نیافتید."},{"v":11,"t":"نه آنکه درباره احتیاج سخن می‌گویم، زیرا که آموخته‌ام که در هر حالتی که باشم، قناعت کنم."},{"v":12,"t":"و ذلت رامی دانم و دولتمندی را هم می‌دانم، در هرصورت و در همه‌چیز، سیری و گرسنگی ودولتنمدی و افلاس را یاد گرفته‌ام."},{"v":13,"t":"قوت هرچیز را دارم در مسیح که مرا تقویت می‌بخشد."},{"v":14,"t":"لیکن نیکویی کردید که در تنگی من شریک شدید."},{"v":15,"t":"اما‌ای فیلیپیان شما هم آگاهید که درابتدای انجیل، چون از مکادونیه روانه شدم، هیچ کلیسا در امر دادن و گرفتن با من شراکت نکرد جزشما و بس."},{"v":16,"t":"زیرا که در تسالونیکی هم یک دودفعه برای احتیاج من فرستادید."},{"v":17,"t":"نه آنکه طالب بخشش باشم، بلکه طالب ثمری هستم که به حساب شما بیفزاید."},{"v":18,"t":"ولی همه‌چیز بلکه بیشتر از کفایت دارم. پر گشته‌ام چونکه هدایای شما را از اپفردتس یافته‌ام که عطر خوشبوی و قربانی مقبول و پسندیده خداست."},{"v":19,"t":"اماخدای من همه احتیاجات شما را برحسب دولت خود در جلال در مسیح عیسی رفع خواهد نمود."},{"v":20,"t":"و خدا و پدر ما را تا ابدالابادجلال باد. آمین."},{"v":21,"t":"هر مقدس را در مسیح عیسی سلام برسانید. و برادرانی که با من می‌باشند به شماسلام می‌فرستند."},{"v":22,"t":"جمیع مقدسان به شما سلام می‌رسانند، علی الخصوص آنانی که از اهل خانه قیصر هستند."},{"v":23,"t":"فیض خداوند ما عیسی مسیح باجمیع شما باد. آمین."}],"en":[{"v":1,"t":"Therefore, my brothers, beloved and longed for, my joy and crown, stand firm in the Lord in this way, my beloved."},{"v":2,"t":"I exhort Euodia, and I exhort Syntyche, to think the same way in the Lord."},{"v":3,"t":"Yes, I beg you also, true partner, help these women, for they labored with me in the Good News with Clement also, and the rest of my fellow workers, whose names are in the book of life."},{"v":4,"t":"Rejoice in the Lord always! Again I will say, “Rejoice!”"},{"v":5,"t":"Let your gentleness be known to all men. The Lord is at hand."},{"v":6,"t":"In nothing be anxious, but in everything, by prayer and petition with thanksgiving, let your requests be made known to God."},{"v":7,"t":"And the peace of God, which surpasses all understanding, will guard your hearts and your thoughts in Christ Jesus."},{"v":8,"t":"Finally, brothers, whatever things are true, whatever things are honorable, whatever things are just, whatever things are pure, whatever things are lovely, whatever things are of good report: if there is any virtue and if there is anything worthy of praise, think about these things."},{"v":9,"t":"Do the things which you learned, received, heard, and saw in me, and the God of peace will be with you."},{"v":10,"t":"But I rejoice in the Lord greatly that now at length you have revived your thought for me; in which you did indeed take thought, but you lacked opportunity."},{"v":11,"t":"Not that I speak because of lack, for I have learned in whatever state I am, to be content in it."},{"v":12,"t":"I know how to be humbled, and I also know how to abound. In any and all circumstances I have learned the secret both to be filled and to be hungry, both to abound and to be in need."},{"v":13,"t":"I can do all things through Christ who strengthens me."},{"v":14,"t":"However you did well that you shared in my affliction."},{"v":15,"t":"You yourselves also know, you Philippians, that in the beginning of the Good News, when I departed from Macedonia, no assembly shared with me in the matter of giving and receiving but you only."},{"v":16,"t":"For even in Thessalonica you sent once and again to my need."},{"v":17,"t":"Not that I seek for the gift, but I seek for the fruit that increases to your account."},{"v":18,"t":"But I have all things and abound. I am filled, having received from Epaphroditus the things that came from you, a sweet-smelling fragrance, an acceptable and well-pleasing sacrifice to God."},{"v":19,"t":"My God will supply every need of yours according to his riches in glory in Christ Jesus."},{"v":20,"t":"Now to our God and Father be the glory forever and ever! Amen."},{"v":21,"t":"Greet every saint in Christ Jesus. The brothers who are with me greet you."},{"v":22,"t":"All the saints greet you, especially those who are of Caesar’s household."},{"v":23,"t":"The grace of the Lord Jesus Christ be with you all. Amen."}],"hr":[{"v":1,"t":"Stoga, braćo moja ljubljena i željkovana, radosti moja i vijenče moj, tako - čvrsto stojte u Gospodinu."},{"v":2,"t":"Evodiju zaklinjem, i Sintihu zaklinjem da budu složne u Gospodinu."},{"v":3,"t":"Da, molim i tebe, čestiti druže, pomaži im jer su se one u evanđelju borile zajedno sa mnom, i s Klementom i ostalim mojim suradnicima, kojih su imena u knjizi Života."},{"v":4,"t":"Radujte se u Gospodinu uvijek! Ponavljam: radujte se!"},{"v":5,"t":"Blagost vaša neka je znana svim ljudima! Gospodin je blizu!"},{"v":6,"t":"Ne budite zabrinuti ni za što, nego u svemu - molitvom i prošnjom, sa zahvaljivanjem - očitujte svoje molbe Bogu."},{"v":7,"t":"I mir Božji koji je iznad svakog razuma čuvat će srca vaša i vaše misli u Kristu Isusu."},{"v":8,"t":"Uostalom, braćo, što je god istinito, što god časno, što god pravedno, što god čisto, što god ljubazno, što god hvalevrijedno; je li što krepost, je li što pohvala - to nek vam je na srcu!"},{"v":9,"t":"Što ste naučili, i primili, i čuli, i vidjeli na meni - to činite i Bog mira bit će s vama!"},{"v":10,"t":"Uvelike se obradovah u Gospodinu što ste napokon procvali te mislite na me; mislili ste i prije, ali niste imali prigode."},{"v":11,"t":"Govorim to ne zbog oskudice, ta naučen sam u svakoj prigodi biti zadovoljan."},{"v":12,"t":"Znam i oskudijevati, znam i obilovati! Na sve sam i na svašta navikao: i sit biti i gladovati, i obilovati i oskudijevati."},{"v":13,"t":"Sve mogu u Onome koji me jača!"},{"v":14,"t":"Ipak, lijepo je od vas što sa mnom podijeliste moju nevolju."},{"v":15,"t":"A i vi, Filipljani, znate: u početku evanđelja, kad otputovah iz Makedonije, nijedna mi se Crkva nije pridružila u pogledu izdataka i primitaka, doli vi jedini."},{"v":16,"t":"Čak ste mi i u Solun i jednom, i dvaput, za potrebe poslali."},{"v":17,"t":"Ne, ne tražim dara; tražim samo plod izobilan u vašu korist."},{"v":18,"t":"Imam svega i u izobilju; namiren sam otkad po Epafroditu primih ono od vas, miris ugodan, žrtvu milu, ugodnu Bogu."},{"v":19,"t":"A Bog moj ispunit će svaku vašu potrebu po bogatstvu svome, veličanstveno, u Kristu Isusu."},{"v":20,"t":"Bogu pak, Ocu našemu, slava u vijeke vjekova! Amen."},{"v":21,"t":"Pozdravite svakoga svetog u Kristu Isusu. Pozdravljaju vas braća koja su sa mnom."},{"v":22,"t":"Pozdravljaju vas svi sveti, ponajpače oni iz careva dvora."},{"v":23,"t":"Milost Gospodina Isusa Krista s duhom vašim!"}]}},"COL":{"1":{"fa":[{"v":1,"t":"پولس به اراده خدا رسول مسیح عیسی وتیموتاوس برادر،"},{"v":2,"t":"به مقدسان در کولسی و برادران امین، در مسیح فیض و سلامتی از جانب پدر ما خداو عیسی مسیح خداوند بر شما باد."},{"v":3,"t":"خدا و پدر خداوند خود عیسی مسیح راشکر می‌کنیم و پیوسته برای شما دعا می‌نماییم،"},{"v":4,"t":"چونکه ایمان شما را در مسیح عیسی و محبتی را که با جمیع مقدسان می‌نمایید شنیدیم،"},{"v":5,"t":"به‌سبب امیدی که بجهت شما در آسمان گذاشته شده است که خبر آن را در کلام راستی انجیل سابق شنیدید،"},{"v":6,"t":"که به شما وارد شد چنانکه درتمامی عالم نیز و میوه می‌آورد و نمو می‌کند، چنانکه در میان شما نیز از روزی که آن را شنیدیدو فیض خدا را در راستی دانسته‌اید."},{"v":7,"t":"چنانکه ازاپفراس تعلیم یافتید که همخدمت عزیز ما وخادم امین مسیح برای شما است."},{"v":8,"t":"و او ما را نیز ازمحبت شما که در روح است خبر داد."},{"v":9,"t":"و از آن جهت ما نیز از روزی که این راشنیدیم، باز نمی ایستیم از دعا کردن برای شما ومسالت نمودن تا از کمال معرفت اراده او در هرحکمت و فهم روحانی پر شوید،"},{"v":10,"t":"تا شما به طریق شایسته خداوند به‌کمال رضامندی رفتارنمایید و در هر عمل نیکو بار آورید و به معرفت کامل خدا نمو کنید،"},{"v":11,"t":"و به اندازه توانایی جلال او به قوت تمام زورآور شوید تا صبر کامل وتحمل را با شادمانی داشته باشید؛"},{"v":12,"t":"و پدر راشکر گزارید که ما را لایق بهره میراث مقدسان درنور گردانیده است،"},{"v":13,"t":"و ما را از قدرت ظلمت رهانیده، به ملکوت پسر محبت خود منتقل ساخت،"},{"v":14,"t":"که در وی فدیه خود یعنی آمرزش گناهان خویش را یافته‌ایم."},{"v":15,"t":"و او صورت خدای نادیده است، نخست زاده تمامی آفریدگان."},{"v":16,"t":"زیرا که در اوهمه‌چیز آفریده شد، آنچه در آسمان و آنچه برزمین است از چیزهای دیدنی و نادیدنی و تختهاو سلطنتها و ریاسات و قوات؛ همه بوسیله او وبرای او آفریده شد."},{"v":17,"t":"و او قبل از همه است و دروی همه‌چیز قیام دارد."},{"v":18,"t":"و او بدن یعنی کلیسا راسر است، زیرا که او ابتدا است و نخست زاده ازمردگان تا در همه‌چیز او مقدم شود."},{"v":19,"t":"زیرا خدارضا بدین داد که تمامی پری در او ساکن شود،"},{"v":20,"t":"و اینکه بوساطت او همه‌چیز را با خودمصالحه دهد، چونکه به خون صلیب وی سلامتی را پدید آورد. بلی بوسیله او خواه آنچه بر زمین وخواه آنچه در آسمان است."},{"v":21,"t":"و شما را که سابق از نیت دل در اعمال بد خویش اجنبی و دشمن بودید، بالفعل مصالحه داده است،"},{"v":22,"t":"در بدن بشری خود بوسیله موت تا شما را در حضورخود مقدس و بی‌عیب و بی‌ملامت حاضر سازد،"},{"v":23,"t":"به شرطی که در ایمان بنیاد نهاده و قایم بمانیدو جنبش نخورید از امید انجیل که در آن تعلیم یافته‌اید و به تمامی خلقت زیر آسمان بدان موعظه شده است و من پولس خادم آن شده‌ام."},{"v":24,"t":"الان از زحمتهای خود در راه شما شادی می‌کنم و نقصهای زحمات مسیح را در بدن خودبه‌کمال می‌رسانم برای بدن او که کلیسا است،"},{"v":25,"t":"که من خادم آن گشته‌ام برحسب نظارت خداکه به من برای شما سپرده شد تا کلام خدا را به‌کمال رسانم؛"},{"v":26,"t":"یعنی آن سری که از دهرها وقرنها مخفی داشته شده بود، لیکن الحال به مقدسان او مکشوف گردید،"},{"v":27,"t":"که خدا اراده نمودتا بشناساند که چیست دولت جلال این سر درمیان امت‌ها که آن مسیح در شما و امید جلال است."},{"v":28,"t":"و ما او را اعلان می‌نماییم، در حالتیکه هر شخص را تنبیه می‌کنیم و هر کس را به هرحکمت تعلیم می‌دهیم تا هرکس را کامل درمسیح عیسی حاضر سازیم."},{"v":29,"t":"و برای این نیزمحنت می‌کشم و مجاهده می‌نمایم بحسب عمل او که در من به قوت عمل می‌کند."}],"en":[{"v":1,"t":"Paul, an apostle of Christ Jesus through the will of God, and Timothy our brother,"},{"v":2,"t":"to the saints and faithful brothers in Christ at Colossae: Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":3,"t":"We give thanks to God the Father of our Lord Jesus Christ, praying always for you,"},{"v":4,"t":"having heard of your faith in Christ Jesus and of the love which you have toward all the saints,"},{"v":5,"t":"because of the hope which is laid up for you in the heavens, of which you heard before in the word of the truth of the Good News"},{"v":6,"t":"which has come to you, even as it is in all the world and is bearing fruit and growing, as it does in you also, since the day you heard and knew the grace of God in truth,"},{"v":7,"t":"even as you learned from Epaphras our beloved fellow servant, who is a faithful servant of Christ on your behalf,"},{"v":8,"t":"who also declared to us your love in the Spirit."},{"v":9,"t":"For this cause, we also, since the day we heard this, don’t cease praying and making requests for you, that you may be filled with the knowledge of his will in all spiritual wisdom and understanding,"},{"v":10,"t":"that you may walk worthily of the Lord, to please him in all respects, bearing fruit in every good work and increasing in the knowledge of God,"},{"v":11,"t":"strengthened with all power, according to the might of his glory, for all endurance and perseverance with joy,"},{"v":12,"t":"giving thanks to the Father, who made us fit to be partakers of the inheritance of the saints in light,"},{"v":13,"t":"who delivered us out of the power of darkness, and translated us into the Kingdom of the Son of his love,"},{"v":14,"t":"in whom we have our redemption, the forgiveness of our sins."},{"v":15,"t":"He is the image of the invisible God, the firstborn of all creation."},{"v":16,"t":"For by him all things were created in the heavens and on the earth, visible things and invisible things, whether thrones or dominions or principalities or powers. All things have been created through him and for him."},{"v":17,"t":"He is before all things, and in him all things are held together."},{"v":18,"t":"He is the head of the body, the assembly, who is the beginning, the firstborn from the dead, that in all things he might have the preeminence."},{"v":19,"t":"For all the fullness was pleased to dwell in him,"},{"v":20,"t":"and through him to reconcile all things to himself by him, whether things on the earth or things in the heavens, having made peace through the blood of his cross."},{"v":21,"t":"You, being in past times alienated and enemies in your mind in your evil deeds,"},{"v":22,"t":"yet now he has reconciled in the body of his flesh through death, to present you holy and without defect and blameless before him,"},{"v":23,"t":"if it is so that you continue in the faith, grounded and steadfast, and not moved away from the hope of the Good News which you heard, which was proclaimed in all creation under heaven, of which I, Paul, was made a servant."},{"v":24,"t":"Now I rejoice in my sufferings for your sake, and fill up on my part that which is lacking of the afflictions of Christ in my flesh for his body’s sake, which is the assembly,"},{"v":25,"t":"of which I was made a servant according to the stewardship of God which was given me toward you to fulfill the word of God,"},{"v":26,"t":"the mystery which has been hidden for ages and generations. But now it has been revealed to his saints,"},{"v":27,"t":"to whom God was pleased to make known what are the riches of the glory of this mystery among the Gentiles, which is Christ in you, the hope of glory."},{"v":28,"t":"We proclaim him, admonishing every man and teaching every man in all wisdom, that we may present every man perfect in Christ Jesus;"},{"v":29,"t":"for which I also labor, striving according to his working, which works in me mightily."}],"hr":[{"v":1,"t":"Pavao, po volji Božjoj apostol Krista Isusa, i brat Timotej:"},{"v":2,"t":"Kološanima, svetoj i vjernoj braći u Kristu. Milost vam i mir od Boga, Oca našega!"},{"v":3,"t":"Zahvaljujemo Bogu, Ocu Gospodina našega Isusa Krista, svagda za vas moleći."},{"v":4,"t":"Jer čuli smo za vašu vjeru u Kristu Isusu i za ljubav koju gajite prema svima svetima"},{"v":5,"t":"poradi nade koja vam je pohranjena u nebesima. Za nju ste već čuli u Riječi istine -"},{"v":6,"t":"evanđelju koje je do vas doprlo te plodove nosi i raste, kao što po svem svijetu, tako i među vama od dana kad ste čuli i spoznali milost Božju po istini,"},{"v":7,"t":"kako ste naučili od ljubljenog Epafre, sluge zajedno s nama; on je umjesto nas, vjeran poslužitelj Kristov,"},{"v":8,"t":"on nas je i obavijestio o vašoj ljubavi u Duhu."},{"v":9,"t":"Zato i mi, od dana kada to čusmo, neprestano za vas molimo i ištemo da se ispunite spoznajom volje Njegove u svoj mudrosti i shvaćanju duhovnome:"},{"v":10,"t":"da živite dostojno Gospodina i posve mu ugodite, plodni svakim dobrim djelom i rastući u spoznaji Božjoj;"},{"v":11,"t":"osnaženi svakom snagom, po sili Slave njegove, za svaku postojanost i strpljivost;"},{"v":12,"t":"s radošću zahvaljujući Ocu koji vas osposobi za dioništvo u baštini svetih u svjetlosti."},{"v":13,"t":"On nas izbavi iz vlasti tame i prenese u kraljevstvo Sina, ljubavi svoje,"},{"v":14,"t":"u kome imamo otkupljenje, otpuštenje grijeha."},{"v":15,"t":"On je slika Boga nevidljivoga, Prvorođenac svakog stvorenja."},{"v":16,"t":"Ta u njemu je sve stvoreno na nebesima i na zemlji, vidljivo i nevidljivo, bilo Prijestolja, bilo Gospodstva, bilo Vrhovništva, bilo Vlasti - sve je po njemu i za njega stvoreno:"},{"v":17,"t":"on je prije svega i sve stoji u njemu."},{"v":18,"t":"On je Glava Tijela, Crkve; on je Početak, Prvorođenac od mrtvih, da u svemu bude Prvak."},{"v":19,"t":"Jer svidjelo se Bogu u njemu nastaniti svu Puninu"},{"v":20,"t":"i po njemu - uspostavivši mir krvlju križa njegova - izmiriti sa sobom sve, bilo na zemlji, bilo na nebesima."},{"v":21,"t":"I vas, nekoć po zlim djelima udaljene i neprijateljski raspoložene,"},{"v":22,"t":"sada u ljudskom tijelu Kristovu, po smrti, sa sobom izmiri da vas k sebi privede svete, bez mane i besprigovorne."},{"v":23,"t":"Samo ako ostanete u vjeri utemeljeni, stalni i nepoljuljani u nadi evanđelja koje čuste, koje se propovijeda svakom stvorenju pod nebom, a ja mu, Pavao, postadoh poslužiteljem."},{"v":24,"t":"Radujem se sada dok trpim za vas i u svom tijelu dopunjam što nedostaje mukama Kristovim za Tijelo njegovo, za Crkvu."},{"v":25,"t":"Njoj ja postadoh poslužiteljem po rasporedbi Božjoj koja mi je dana za vas da potpuno pronesem Riječ Božju -"},{"v":26,"t":"otajstvo pred vjekovima i pred naraštajima skriveno, a sada očitovano svetima njegovim."},{"v":27,"t":"Njima Bog htjede obznaniti kako li je slavom bogato to otajstvo među poganima: to jest Krist u vama, nada slave!"},{"v":28,"t":"Njega mi navješćujemo, opominjući svakoga čovjeka, poučavajući svakoga čovjeka u svoj mudrosti da bismo svakoga čovjeka doveli do savršenstva u Kristu."},{"v":29,"t":"Za to se i trudim i borim njegovom djelotvornošću koja u meni snažno djeluje."}]},"2":{"fa":[{"v":1,"t":"زیرا می‌خواهم شما آگاه باشید که مرا چه نوع اجتهاد است برای شما و اهل لاودکیه و آنانی که صورت مرا در جسم ندیده‌اند،"},{"v":2,"t":"تا دلهای ایشان تسلی یابد و ایشان در محبت پیوند شده، به دولت یقین فهم تمام و به معرفت سر خدا برسند؛"},{"v":3,"t":"یعنی سر مسیح که در وی تمامی خزاین حکمت و علم مخفی است."},{"v":4,"t":"امااین را می‌گویم تا هیچ‌کس شما را به سخنان دلاویز اغوا نکند،"},{"v":5,"t":"زیرا که هرچند در جسم غایبم لیکن در روح با شما بوده، شادی می‌کنم ونظم و استقامت ایمانتان را در مسیح نظاره می‌کنم."},{"v":6,"t":"پس چنانکه مسیح عیسی خداوند راپذیرفتید، در وی رفتار نمایید،"},{"v":7,"t":"که در او ریشه کرده و بنا شده و در ایمان راسخ گشته‌اید، بطوری که تعلیم یافته‌اید و در آن شکرگزاری بسیارمی نمایید."},{"v":8,"t":"باخبر باشید که کسی شما را نرباید به فلسفه و مکر باطل، برحسب تقلید مردم وبرحسب اصول دنیوی نه برحسب مسیح،"},{"v":9,"t":"که دروی از جهت جسم، تمامی پری الوهیت ساکن است."},{"v":10,"t":"و شما در وی تکمیل شده‌اید که سرتمامی ریاست و قدرت است."},{"v":11,"t":"و در وی مختون شده‌اید، به ختنه ناساخته به‌دست یعنی بیرون کردن بدن جسمانی، بوسیله اختتان مسیح."},{"v":12,"t":"و با وی در تعمید مدفون گشتید که در آن هم برخیزانیده شدید به ایمان بر عمل خدا که او را ازمردگان برخیزانید."},{"v":13,"t":"و شما را که در خطایا ونامختونی جسم خود مرده بودید، با او زنده گردانید چونکه همه خطایای شما را آمرزید،"},{"v":14,"t":"و آن دستخطی را که ضد ما و مشتمل برفرایض و به خلاف ما بود محو ساخت و آن را به صلیب خود میخ زده از میان برداشت."},{"v":15,"t":"و ازخویشتن ریاسات و قوات را بیرون کرده، آنها راعلانیه آشکار نمود، چون در آن بر آنها ظفریافت."},{"v":16,"t":"پس کسی درباره خوردن و نوشیدن ودرباره عید و هلال و سبت بر شما حکم نکند،"},{"v":17,"t":"زیرا که اینها سایه چیزهای آینده است، لیکن بدن از آن مسیح است."},{"v":18,"t":"و کسی انعام شما رانرباید از رغبت به فروتنی و عبادت فرشتگان ومداخلت در اموری که دیده است که از ذهن جسمانی خود بی‌جا مغرور شده است؛"},{"v":19,"t":"و به‌سر متمسک نشده که از آن تمامی بدن به توسطمفاصل و بندها مدد یافته و با هم پیوند شده، نمومی کند به نموی که از خداست."},{"v":20,"t":"چونکه بامسیح از اصول دنیوی مردید، چگونه است که مثل زندگان در دنیا بر شما فرایض نهاده می‌شود؟"},{"v":21,"t":"که لمس مکن و مچش بلکه دست مگذار!"},{"v":22,"t":"(که همه اینها محض استعمال فاسد می‌شود)برحسب تقالید و تعالیم مردم،"},{"v":23,"t":"که چنین چیزهاهرچند در عبادت نافله و فروتنی و آزار بدن صورت حکمت دارد، ولی فایده‌ای برای رفع تن پروری ندارد."}],"en":[{"v":1,"t":"For I desire to have you know how greatly I struggle for you and for those at Laodicea, and for as many as have not seen my face in the flesh;"},{"v":2,"t":"that their hearts may be comforted, they being knit together in love, and gaining all riches of the full assurance of understanding, that they may know the mystery of God, both of the Father and of Christ,"},{"v":3,"t":"in whom all the treasures of wisdom and knowledge are hidden."},{"v":4,"t":"Now I say this that no one may delude you with persuasiveness of speech."},{"v":5,"t":"For though I am absent in the flesh, yet I am with you in the spirit, rejoicing and seeing your order, and the steadfastness of your faith in Christ."},{"v":6,"t":"As therefore you received Christ Jesus the Lord, walk in him,"},{"v":7,"t":"rooted and built up in him and established in the faith, even as you were taught, abounding in it in thanksgiving."},{"v":8,"t":"Be careful that you don’t let anyone rob you through his philosophy and vain deceit, after the tradition of men, after the elemental spirits of the world, and not after Christ."},{"v":9,"t":"For in him all the fullness of the Deity dwells bodily,"},{"v":10,"t":"and in him you are made full, who is the head of all principality and power."},{"v":11,"t":"In him you were also circumcised with a circumcision not made with hands, in the putting off of the body of the sins of the flesh, in the circumcision of Christ,"},{"v":12,"t":"having been buried with him in baptism, in which you were also raised with him through faith in the working of God, who raised him from the dead."},{"v":13,"t":"You were dead through your trespasses and the uncircumcision of your flesh. He made you alive together with him, having forgiven us all our trespasses,"},{"v":14,"t":"wiping out the handwriting in ordinances which was against us. He has taken it out of the way, nailing it to the cross."},{"v":15,"t":"Having stripped the principalities and the powers, he made a show of them openly, triumphing over them in it."},{"v":16,"t":"Let no one therefore judge you in eating or drinking, or with respect to a feast day or a new moon or a Sabbath day,"},{"v":17,"t":"which are a shadow of the things to come; but the body is Christ’s."},{"v":18,"t":"Let no one rob you of your prize by self-abasement and worshiping of the angels, dwelling in the things which he has not seen, vainly puffed up by his fleshly mind,"},{"v":19,"t":"and not holding firmly to the Head, from whom all the body, being supplied and knit together through the joints and ligaments, grows with God’s growth."},{"v":20,"t":"If you died with Christ from the elemental spirits of the world, why, as though living in the world, do you subject yourselves to ordinances,"},{"v":21,"t":"“Don’t handle, nor taste, nor touch”"},{"v":22,"t":"(all of which perish with use), according to the precepts and doctrines of men?"},{"v":23,"t":"These things indeed appear like wisdom in self-imposed worship, humility, and severity to the body, but aren’t of any value against the indulgence of the flesh."}],"hr":[{"v":1,"t":"Htio bih uistinu da znate koliko mi se boriti za vas, za one u Laodiceji i za sve koji me nisu vidjeli licem u lice:"},{"v":2,"t":"da se ohrabre srca njihova, povezana u ljubavi, te se vinu do svega bogatstva, punine shvaćanja, do spoznanja otajstva Božjega - Krista,"},{"v":3,"t":"u kojem su sva bogatstva mudrosti i spoznaje skrivena."},{"v":4,"t":"To govorim zato da vas tko ne prevari zavodljivim riječima."},{"v":5,"t":"Jer ako sam tijelom nenazočan, duhom sam ipak s vama: s radošću promatram vaš red i čvrstoću vaše vjere u Krista."},{"v":6,"t":"Kao što primiste Krista Isusa, Gospodina, tako u njemu živite:"},{"v":7,"t":"ukorijenjeni i nazidani na njemu i učvršćeni vjerom kako ste poučeni, obilujte zahvaljivanjem."},{"v":8,"t":"Pazite da vas tko ne odvuče mudrovanjem i ispraznim zavaravanjem što se oslanja na predaju ljudsku, na “počela svijeta”, a ne na Krista."},{"v":9,"t":"Jer u njemu tjelesno prebiva sva punina božanstva; te ste i vi"},{"v":10,"t":"ispunjeni u njemu, koji je glava svakoga Vrhovništva i Vlasti."},{"v":11,"t":"U njemu ste i obrezani obrezanjem nerukotvorenim - svukoste tijelo puteno - obrezanjem Kristovim:"},{"v":12,"t":"s njime suukopani u krštenju, u njemu ste i suuskrsli po vjeri u snagu Boga koji ga uskrisi od mrtvih."},{"v":13,"t":"On i vas, koji bijaste mrtvi zbog prijestupa i neobrezanosti svoga tijela, i vas on oživi zajedno s njime. Milostivo nam je oprostio sve prijestupe,"},{"v":14,"t":"izbrisao zadužnicu koja propisima bijaše protiv nas, protivila nam se. Nju on ukloni pribivši je na križ."},{"v":15,"t":"Skinu Vrhovništva i Vlasti, javno to pokaza: u pobjedničkoj ih povorci s njime vodi."},{"v":16,"t":"Neka vas dakle nitko ne sudi po jelu ili po piću, po blagdanima, mlađacima ili subotama."},{"v":17,"t":"To je tek sjena onoga što dolazi, a zbiljnost jest - tijelo Kristovo."},{"v":18,"t":"Nitko neka vas ne podcjenjuje zato što on sam uživa u “poniznosti i štovanju anđela”, zadubljuje se u svoja viđenja, bezrazložno se nadima tjelesnom pameću svojom,"},{"v":19,"t":"a ne drži se Glave, Njega od kojeg sve Tijelo, zglobovima i svezama zbrinuto i povezano, raste rastom Božjim."},{"v":20,"t":"Ako ste s Kristom umrli za počela svijeta, zašto se, kao da još u ovom svijetu živite, dajete pod propise:"},{"v":21,"t":"“Ne diraj, ne kušaj, ne dotiči”?"},{"v":22,"t":"Sve će to uporabom propasti. Uredbe i nauci ljudski!"},{"v":23,"t":"Po samozvanu bogoštovlju, poniznosti i trapljenju tijela sve to doduše slovi kao mudrost, ali nema nikakve vrijednosti, samo zasićuje tijelo."}]},"3":{"fa":[{"v":1,"t":"پس چون با مسیح برخیزانیده شدید، آنچه را که در بالا است بطلبید در آنجایی که مسیح است، به‌دست راست خدا نشسته."},{"v":2,"t":"درآنچه بالا است تفکر کنید، نه در آنچه بر زمین است."},{"v":3,"t":"زیرا که مردید و زندگی شما با مسیح در خدا مخفی است."},{"v":4,"t":"چون مسیح که زندگی مااست ظاهر شود آنگاه شما هم با وی در جلال ظاهر خواهید شد."},{"v":5,"t":"پس اعضای خود را که بر زمین است مقتول سازید، زنا و ناپاکی و هوی و هوس و شهوت قبیح و طمع که بت‌پرستی است"},{"v":6,"t":"که به‌سبب اینهاغضب خدا بر ابنای معصیت وارد می‌آید."},{"v":7,"t":"که شما نیز سابق در اینها رفتار می‌کردید، هنگامی که در آنها زیست می‌نمودید."},{"v":8,"t":"لیکن الحال شماهمه را ترک کنید، یعنی خشم و غیظ و بدخویی وبدگویی و فحش را از زبان خود."},{"v":9,"t":"به یکدیگردروغ مگویید، چونکه انسانیت کهنه را با اعمالش از خود بیرون کرده‌اید،"},{"v":10,"t":"و تازه را پوشیده‌اید که به صورت خالق خویش تا به معرفت کامل، تازه می‌شود،"},{"v":11,"t":"که در آن نه یونانی است، نه یهود، نه ختنه، نه نامختونی، نه بربری، نه سکیتی، نه غلام و نه آزاد، بلکه مسیح همه و در همه است."},{"v":12,"t":"پس مانند برگزیدگان مقدس و محبوب خدا احشای رحمت و مهربانی و تواضع و تحمل و حلم را بپوشید؛"},{"v":13,"t":"و متحمل یکدیگر شده، همدیگر را عفو کنید هرگاه بر دیگری ادعایی داشته باشید؛ چنانکه مسیح شما را آمرزید، شمانیز چنین کنید."},{"v":14,"t":"و بر این همه محبت را که کمربند کمال است بپوشید."},{"v":15,"t":"و سلامتی خدا دردلهای شما مسلط باشد که به آن هم در یک بدن خوانده شده‌اید و شاکر باشید."},{"v":16,"t":"کلام مسیح درشما به دولتمندی و به‌کمال حکمت ساکن بشودو یکدیگر را تعلیم و نصیحت کنید به مزامیر وتسبیحات و سرودهای روحانی و با فیض در دلهای خود خدا را بسرایید."},{"v":17,"t":"و آنچه کنید درقول و فعل، همه را به نام عیسی خداوند بکنید وخدای پدر را بوسیله او شکر کنید."},{"v":18,"t":"‌ای زنان، شوهران خود را اطاعت نمایید، چنانکه در خداوند می‌شاید."},{"v":19,"t":"‌ای شوهران، زوجه های خود را محبت نمایید و با ایشان تلخی مکنید."},{"v":20,"t":"‌ای فرزندان، والدین خود را در همه‌چیز اطاعت کنید زیرا که این پسندیده است درخداوند."},{"v":21,"t":"‌ای پدران، فرزندان خود را خشمگین مسازید، مبادا شکسته دل شوند."},{"v":22,"t":"‌ای غلامان، آقایان جسمانی خود را در هر چیز اطاعت کنید، نه به خدمت حضور مثل جویندگان رضامندی مردم، بلکه به اخلاص قلب و از خداوند بترسید."},{"v":23,"t":"و آنچه کنید، از دل کنید بخاطر خداوند نه به بخاطر انسان."},{"v":24,"t":"چون می‌دانید که از خداوندمکافات میراث را خواهید یافت، چونکه مسیح خداوند را بندگی می‌کنید."},{"v":25,"t":"زیرا هرکه ظلم کند، آن ظلمی را که کرد، خواهد یافت وظاهربینی نیست."}],"en":[{"v":1,"t":"If then you were raised together with Christ, seek the things that are above, where Christ is, seated on the right hand of God."},{"v":2,"t":"Set your mind on the things that are above, not on the things that are on the earth."},{"v":3,"t":"For you died, and your life is hidden with Christ in God."},{"v":4,"t":"When Christ, our life, is revealed, then you will also be revealed with him in glory."},{"v":5,"t":"Put to death therefore your members which are on the earth: sexual immorality, uncleanness, depraved passion, evil desire, and covetousness, which is idolatry."},{"v":6,"t":"For these things’ sake the wrath of God comes on the children of disobedience."},{"v":7,"t":"You also once walked in those, when you lived in them,"},{"v":8,"t":"but now you must put them all away: anger, wrath, malice, slander, and shameful speaking out of your mouth."},{"v":9,"t":"Don’t lie to one another, seeing that you have put off the old man with his doings,"},{"v":10,"t":"and have put on the new man, who is being renewed in knowledge after the image of his Creator,"},{"v":11,"t":"where there can’t be Greek and Jew, circumcision and uncircumcision, barbarian, Scythian, bondservant, or free person; but Christ is all, and in all."},{"v":12,"t":"Put on therefore, as God’s chosen ones, holy and beloved, a heart of compassion, kindness, lowliness, humility, and perseverance;"},{"v":13,"t":"bearing with one another, and forgiving each other, if any man has a complaint against any; even as Christ forgave you, so you also do."},{"v":14,"t":"Above all these things, walk in love, which is the bond of perfection."},{"v":15,"t":"And let the peace of God rule in your hearts, to which also you were called in one body, and be thankful."},{"v":16,"t":"Let the word of Christ dwell in you richly; in all wisdom teaching and admonishing one another with psalms, hymns, and spiritual songs, singing with grace in your heart to the Lord."},{"v":17,"t":"Whatever you do, in word or in deed, do all in the name of the Lord Jesus, giving thanks to God the Father through him."},{"v":18,"t":"Wives, be in subjection to your husbands, as is fitting in the Lord."},{"v":19,"t":"Husbands, love your wives, and don’t be bitter against them."},{"v":20,"t":"Children, obey your parents in all things, for this pleases the Lord."},{"v":21,"t":"Fathers, don’t provoke your children, so that they won’t be discouraged."},{"v":22,"t":"Servants, obey in all things those who are your masters according to the flesh, not just when they are looking, as men pleasers, but in singleness of heart, fearing God."},{"v":23,"t":"And whatever you do, work heartily, as for the Lord and not for men,"},{"v":24,"t":"knowing that from the Lord you will receive the reward of the inheritance; for you serve the Lord Christ."},{"v":25,"t":"But he who does wrong will receive again for the wrong that he has done, and there is no partiality."}],"hr":[{"v":1,"t":"Ako ste suuskrsli s Kristom, tražite što je gore, gdje Krist sjedi zdesna Bogu!"},{"v":2,"t":"Za onim gore težite, ne za zemaljskim!"},{"v":3,"t":"Ta umrijeste i život je vaš skriven s Kristom u Bogu!"},{"v":4,"t":"Kad se pojavi Krist, život vaš, tada ćete se i vi s njime pojaviti u slavi."},{"v":5,"t":"Umrtvite dakle udove svoje zemaljske: bludnost, nečistoću, strasti, zlu požudu i pohlepu - to idolopoklonstvo!"},{"v":6,"t":"Zbog toga dolazi gnjev Božji na sinove neposlušne."},{"v":7,"t":"Tim ste putom i vi nekoć hodili, kad ste u tome živjeli."},{"v":8,"t":"Ali sada i vi odložite sve! Gnjev, srdžba, opakost, hula, prostota van iz vaših usta!"},{"v":9,"t":"Ne varajte jedni druge! Jer svukoste staroga čovjeka s njegovim djelima"},{"v":10,"t":"i obukoste novoga, koji se obnavlja za spoznanje po slici svoga Stvoritelja!"},{"v":11,"t":"Tu više nema: Grk - Židov, obrezanje - neobrezanje, barbar - skit, rob - slobodnjak, nego sve i u svima - Krist."},{"v":12,"t":"Zaodjenite se dakle - kao izabranici Božji, sveti i ljubljeni - u milosrdno srce, dobrostivost, poniznost, blagost, strpljivost"},{"v":13,"t":"te podnosite jedni druge praštajući ako tko ima protiv koga kakvu pritužbu! Kao što je Gospodin vama oprostio, tako i vi!"},{"v":14,"t":"A povrh svega - ljubav! To je sveza savršenstva."},{"v":15,"t":"I mir Kristov neka upravlja srcima vašim - mir na koji ste pozvani u jednom tijelu! I zahvalni budite!"},{"v":16,"t":"Riječ Kristova neka u svem bogatstvu prebiva u vama! U svakoj se mudrosti poučavajte i urazumljujte! Psalmima, hvalospjevima, pjesmama duhovnim od srca pjevajte hvalu Bogu!"},{"v":17,"t":"I sve što god riječju ili djelom činite, sve činite u imenu Gospodina Isusa, zahvaljujući Bogu Ocu po njemu!"},{"v":18,"t":"Žene, pokoravajte se svojim muževima kao što dolikuje u Gospodinu!"},{"v":19,"t":"Muževi, ljubite svoje žene i ne budite osorni prema njima."},{"v":20,"t":"Djeco, slušajte roditelje u svemu, ta to je milo u Gospodinu!"},{"v":21,"t":"Očevi, ne ogorčujte svoje djece da ne klonu duhom."},{"v":22,"t":"Robovi, slušajte u svemu svoje zemaljske gospodare! Ne naoko, kao oni koji se ulaguju ljudima, nego u jednostavnosti srca, bojeći se Gospodina."},{"v":23,"t":"Što god radite, zdušno činite, kao Gospodinu, a ne ljudima,"},{"v":24,"t":"znajući da ćete od Gospodina primiti nagradu, baštinu. Gospodinu Kristu služite."},{"v":25,"t":"Doista, nepravedniku će se uzvratiti što je nepravedno učinio. Ne, nema pristranosti!"}]},"4":{"fa":[{"v":1,"t":"ای آقایان، با غلامان خود عدل و انصاف رابه‌جا آرید، چونکه می‌دانید شما را نیزآقایی هست در آسمان."},{"v":2,"t":"در دعا مواظب باشید و در آن با شکرگزاری بیدار باشید."},{"v":3,"t":"و درباره ما نیز دعا کنید که خدا در کلام را به روی ما بگشاید تا سر مسیح را که بجهت آن در قید هم افتاده‌ام بگویم،"},{"v":4,"t":"و آن رابطوری که می‌باید تکلم کنم و مبین سازم."},{"v":5,"t":"زمان را دریافته، پیش اهل خارج به حکمت رفتار کنید."},{"v":6,"t":"گفتگوی شما همیشه با فیض باشد و اصلاح شده به نمک، تا بدانید هرکس را چگونه جواب باید داد."},{"v":7,"t":"تیخیکس، برادر عزیز و خادم امین وهمخدمت من در خداوند، از همه احوال من شمارا خواهد آگاهانید،"},{"v":8,"t":"که او را به همین جهت نزدشما فرستادم تا از حالات شما آگاه شود و دلهای شما را تسلی دهد،"},{"v":9,"t":"با انیسیمس، برادر امین وحبیب که از خود شماست، شما را از همه گزارش اینجا آگاه خواهند ساخت."},{"v":10,"t":"ارسترخس همزندان من شما را سلام می‌رساند، و مرقس عموزاده برنابا که درباره او حکم یافته‌اید، هرگاه نزد شما آید او را بپذیرید،"},{"v":11,"t":"و یسوع، ملقب به یسطس که ایشان تنها از اهل ختنه برای ملکوت خدا همخدمت شده، باعث تسلی من گردیدند."},{"v":12,"t":"اپفراس به شما سلام می‌رساند که یکی از شماو غلام مسیح است و پیوسته برای شما دردعاهای خود جد و جهد می‌کند تا در تمامی اراده خدا کامل و متیقن شوید."},{"v":13,"t":"و برای اوگواهی می‌دهم که درباره شما و اهل لاودکیه واهل هیراپولس بسیار محنت می‌کشد."},{"v":14,"t":"و لوقای طبیب حبیب و دیماس به شما سلام می‌رسانند."},{"v":15,"t":"برادران در لاودکیه و نیمفاس و کلیسایی را که در خانه ایشان است سلام رسانید."},{"v":16,"t":"و چون این رساله برای شما خوانده شد، مقرر دارید که در کلیسای لاودکیان نیز خوانده شود و رساله از لاودکیه را هم شما بخوانید."},{"v":17,"t":"و به ارخپس گویید: «باخبر باش تا آن خدمتی را که در خداوند یافته‌ای به‌کمال رسانی.»"},{"v":18,"t":"تحیت من، پولس، به‌دست خودم. زنجیرهای مرا بخاطر دارید. فیض با شما باد. آمین."}],"en":[{"v":1,"t":"Masters, give to your servants that which is just and equal, knowing that you also have a Master in heaven."},{"v":2,"t":"Continue steadfastly in prayer, watching in it with thanksgiving,"},{"v":3,"t":"praying together for us also, that God may open to us a door for the word, to speak the mystery of Christ, for which I am also in bonds,"},{"v":4,"t":"that I may reveal it as I ought to speak."},{"v":5,"t":"Walk in wisdom toward those who are outside, redeeming the time."},{"v":6,"t":"Let your speech always be with grace, seasoned with salt, that you may know how you ought to answer each one."},{"v":7,"t":"All my affairs will be made known to you by Tychicus, the beloved brother, faithful servant, and fellow bondservant in the Lord."},{"v":8,"t":"I am sending him to you for this very purpose, that he may know your circumstances and comfort your hearts,"},{"v":9,"t":"together with Onesimus, the faithful and beloved brother, who is one of you. They will make known to you everything that is going on here."},{"v":10,"t":"Aristarchus, my fellow prisoner, greets you, and Mark the cousin of Barnabas (concerning whom you received instructions, “if he comes to you, receive him”),"},{"v":11,"t":"and Jesus who is called Justus. These are my only fellow workers for God’s Kingdom who are of the circumcision, men who have been a comfort to me."},{"v":12,"t":"Epaphras, who is one of you, a servant of Christ, salutes you, always striving for you in his prayers, that you may stand perfect and complete in all the will of God."},{"v":13,"t":"For I testify about him that he has great zeal for you, and for those in Laodicea, and for those in Hierapolis."},{"v":14,"t":"Luke the beloved physician and Demas greet you."},{"v":15,"t":"Greet the brothers who are in Laodicea, with Nymphas and the assembly that is in his house."},{"v":16,"t":"When this letter has been read among you, cause it to be read also in the assembly of the Laodiceans, and that you also read the letter from Laodicea."},{"v":17,"t":"Tell Archippus, “Take heed to the ministry which you have received in the Lord, that you fulfill it.”"},{"v":18,"t":"I, Paul, write this greeting with my own hand. Remember my chains. Grace be with you. Amen."}],"hr":[{"v":1,"t":"Gospodari, pružajte svojim robovima što je pravo i pravično, znajući da i vi imate Gospodina na nebu!"},{"v":2,"t":"U molitvi ustrajte, bdijte u njoj u zahvaljivanju!"},{"v":3,"t":"Molite ujedno i za nas: da nam Bog otvori vrata riječi te propovijedamo otajstvo Kristovo, za koje sam i okovan;"},{"v":4,"t":"da ga očitujem propovijedajući kako treba."},{"v":5,"t":"Mudro se ponašajte prema onima vani: iskupljujte vrijeme!"},{"v":6,"t":"Riječ neka vam je uvijek ljubazna, solju začinjena: znajte svakomu odgovoriti kako treba."},{"v":7,"t":"Što je sa mnom - o svemu će vas obavijestiti Tihik, ljubljeni brat, vjerni poslužitelj i sa mnom sluga u Gospodinu."},{"v":8,"t":"Njega šaljem k vama baš zato da znate kako smo i da ohrabri srca vaša."},{"v":9,"t":"Šaljem ga s Onezimom, vjernim i ljubljenim bratom, koji je vaš zemljak: oni će vam priopćiti kako je ovdje."},{"v":10,"t":"Pozdravlja vas Aristarh, suuznik moj. I Marko, nećak Barnabin, o kome primiste naredbe: dođe li k vama, lijepo ga primite."},{"v":11,"t":"Pozdravlja vas i Isus, zvani Just. Od onih koji su iz obrezanja samo su mi ovi suradnici na kraljevstvu Božjemu, oni mi bijahu utjehom."},{"v":12,"t":"Pozdravlja vas Epafra, vaš zemljak, sluga Krista Isusa; on se uvijek bori za vas u molitvama: da se održite, savršeni i ispunjeni, u posvemašnjoj volji Božjoj."},{"v":13,"t":"Svjedočim doista za nj: mnogo se trudi za vas i za one u Laodiceji i one u Hierapolu."},{"v":14,"t":"Pozdravlja vas Luka, ljubljeni liječnik, i Dema."},{"v":15,"t":"Pozdravite braću u Laodiceji, i Nimfu i Crkvu u njezinoj kući."},{"v":16,"t":"A kad se ova poslanica pročita kod vas, pobrinite se da se pročita i u Laodicejskoj crkvi, i vi da pročitate onu iz Laodiceje."},{"v":17,"t":"I recite Arhipu: “Pazi na službu koju si primio u Gospodinu: ispuni je!”"},{"v":18,"t":"Pozdrav mojom rukom, Pavlovom! Spominjite se mojih okova! Milost s vama!"}]}},"1TH":{"1":{"fa":[{"v":1,"t":"پولس و سلوانس و تیموتاوس، به کلیسای تسالونیکیان که در خدای پدر وعیسی مسیح خداوند می‌باشید. فیض و سلامتی از جانب پدر ما خدا و عیسی مسیح خداوند با شما باد."},{"v":2,"t":"پیوسته درباره جمیع شما خدا را شکرمی کنیم و دائم در دعاهای خود شما را ذکرمی نماییم،"},{"v":3,"t":"چون اعمال ایمان شما و محنت محبت و صبر امید شما را در خداوند ما عیسی مسیح در حضور خدا و پدر خود یاد می‌کنیم."},{"v":4,"t":"زیرا که‌ای برادران و‌ای عزیزان خدا، ازبرگزیده شدن شما مطلع هستیم،"},{"v":5,"t":"زیرا که انجیل ما بر شما محض سخن وارد نشده، بلکه با قوت وروح‌القدس و یقین کامل، چنانکه می‌دانید که درمیان شما بخاطر شما چگونه مردمان شدیم."},{"v":6,"t":"وشما به ما و به خداوند اقتدا نمودید و کلام را درزحمت شدید، با خوشی روح‌القدس پذیرفتید،"},{"v":7,"t":"به حدی که شما جمیع ایمانداران مکادونیه واخائیه را نمونه شدید،"},{"v":8,"t":"بنوعی که از شما کلام خداوند نه فقط در مکادونیه و اخائیه نواخته شد، بلکه در هرجا ایمان شما به خدا شیوع یافت، بقسمی که احتیاج نیست که ما چیزی بگوییم،"},{"v":9,"t":"زیرا خود ایشان درباره ما خبر می‌دهند که چه قسم وارد به شما شدیم و به چه نوع شما از بتها به سوی خدا بازگشت کردید تا خدای حی حقیقی را بندگی نمایید،"},{"v":10,"t":"و تا پسر او را از آسمان انتظاربکشید که او را از مردگان برخیزانید، یعنی عیسی که ما را از غضب آینده می‌رهاند."}],"en":[{"v":1,"t":"Paul, Silvanus, and Timothy, to the assembly of the Thessalonians in God the Father and the Lord Jesus Christ: Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":2,"t":"We always give thanks to God for all of you, mentioning you in our prayers,"},{"v":3,"t":"remembering without ceasing your work of faith and labor of love and perseverance of hope in our Lord Jesus Christ, before our God and Father."},{"v":4,"t":"We know, brothers loved by God, that you are chosen,"},{"v":5,"t":"and that our Good News came to you not in word only, but also in power, and in the Holy Spirit and with much assurance. You know what kind of men we showed ourselves to be among you for your sake."},{"v":6,"t":"You became imitators of us and of the Lord, having received the word in much affliction, with joy of the Holy Spirit,"},{"v":7,"t":"so that you became an example to all who believe in Macedonia and in Achaia."},{"v":8,"t":"For from you the word of the Lord has been declared, not only in Macedonia and Achaia, but also in every place your faith toward God has gone out, so that we need not to say anything."},{"v":9,"t":"For they themselves report concerning us what kind of a reception we had from you, and how you turned to God from idols to serve a living and true God,"},{"v":10,"t":"and to wait for his Son from heaven, whom he raised from the dead: Jesus, who delivers us from the wrath to come."}],"hr":[{"v":1,"t":"Pavao, Silvan i Timotej Crkvi Solunjana u Bogu Ocu i Gospodinu Isusu Kristu. Milost vam i mir!"},{"v":2,"t":"Zahvaljujemo uvijek Bogu za sve vas i bez prestanka vas se sjećamo u svojim molitvama"},{"v":3,"t":"spominjući se vaše djelotvorne vjere, zauzete ljubavi i postojane nade u Gospodinu našem Isusu Kristu, pred Bogom i Ocem našim."},{"v":4,"t":"Svjesni smo, braćo od Boga ljubljena, vašeg izabranja"},{"v":5,"t":"jer evanđelje naše nije k vama došlo samo u riječi nego i u snazi, u Duhu Svetome i mnogostrukoj punini. Takvi smo, kao što znate, poradi vas među vama bili."},{"v":6,"t":"I vi postadoste nasljedovatelji naši i Gospodinovi: sve u nevolji mnogoj prigrliste Riječ s radošću Duha Svetoga"},{"v":7,"t":"tako da postadoste uzorom svim vjernicima u Makedoniji i Ahaji."},{"v":8,"t":"Od vas je doista ne samo riječ Gospodnja odjeknula po Makedoniji i Ahaji, nego se i vaša vjera u Boga posvuda tako proširila te nije potrebno da o tome govorimo."},{"v":9,"t":"Oni sami o nama pripovijedaju: kako dođosmo k vama, kako se od idola obratiste k Bogu da biste služili Bogu živomu i istinskomu"},{"v":10,"t":"i iščekivali s nebesa Sina njegova koga uskrisi od mrtvih, Isusa koji nas izbavlja od gnjeva što dolazi."}]},"2":{"fa":[{"v":1,"t":"زیرا‌ای برادران، خود می‌دانید که ورود مادر میان شما باطل نبود."},{"v":2,"t":"بلکه هرچند قبل از آن در فیلپی زحمت کشیده و بی‌احترامی دیده بودیم، چنانکه اطلاع دارید، لیکن در خدای خوددلیری کردیم تا انجیل خدا را با جد و جهد شدیدبه شما اعلام نماییم."},{"v":3,"t":"زیرا که نصیحت ما ازگمراهی و خباثت و ریا نیست،"},{"v":4,"t":"بلکه چنانکه مقبول خدا گشتیم که وکلای انجیل بشویم، همچنین سخن می‌گوییم و طالب رضامندی مردم نیستیم، بلکه رضامندی خدایی که دلهای ما رامی آزماید."},{"v":5,"t":"زیرا هرگز سخن تملق‌آمیز نگفتیم، چنانکه می‌دانید، و نه بهانه طمع کردیم، خداشاهد است؛"},{"v":6,"t":"و نه بزرگی از خلق جستیم، نه ازشما و نه از دیگران، هرچند چون رسولان مسیح بودیم، می‌توانستیم سنگین باشیم."},{"v":7,"t":"بلکه در میان شما به ملایمت بسر می‌بردیم، مثل دایه‌ای که اطفال خود را می‌پرورد."},{"v":8,"t":"بدین طرز شایق شماشده، راضی می‌بودیم که نه همان انجیل خدا را به شما دهیم، بلکه جانهای خود را نیز از بس که عزیز ما بودید."},{"v":9,"t":"زانرو که‌ای برادران محنت ومشقت ما را یاد می‌دارید زیرا که شبانه‌روز درکار مشغول شده، به انجیل خدا شما راموعظه می‌کردیم که مبادا بر کسی از شما بارنهیم."},{"v":10,"t":"شما شاهد هستید و خدا نیز که به چه نوع باقدوسیت و عدالت و بی‌عیبی نزد شما که ایماندارهستید رفتار نمودیم."},{"v":11,"t":"چنانکه می‌دانید که هریکی از شما را چون پدر، فرزندان خود رانصیحت و دلداری می‌نمودیم،"},{"v":12,"t":"و وصیت می‌کردیم که رفتار بکنید بطور شایسته خدایی که شما را به ملکوت و جلال خود می‌خواند."},{"v":13,"t":"و ازاینجهت ما نیز دائم خدا را شکر می‌کنیم که چون کلام خدا را که از ما شنیده بودید یافتید، آن راکلام انسانی نپذیرفتید، بلکه چنانکه فی الحقیقه است، کلام خدا که در شما که ایماندار هستیدعمل می‌کند."},{"v":14,"t":"زیرا که‌ای برادران، شما اقتدانمودید به کلیساهای خدا که در یهودیه در مسیح عیسی می‌باشند، زیرا که شما از قوم خود همان زحمات را کشیدید که ایشان نیز از یهود دیدند،"},{"v":15,"t":"که عیسی خداوند و انبیای خود را کشتند و برما جفا کردند؛ و ایشان ناپسند خدا هستند ومخالف جمیع مردم،"},{"v":16,"t":"و ما را منع می‌کنند که به امت‌ها سخن بگوییم تا نجات یابند و همیشه گناهان خود را لبریز می‌کنند، اما منتهای غضب ایشان را فروگرفته است."},{"v":17,"t":"لیکن ما‌ای برادران، چون بقدر ساعتی درظاهر نه در دل از شما مهجور شدیم، به اشتیاق بسیار زیادتر کوشیدیم تا روی شما را ببینیم."},{"v":18,"t":"وبدین جهت یک دو دفعه خواستیم نزد شما بیاییم یعنی من، پولس، لیکن شیطان ما را نگذاشت."},{"v":19,"t":"زیرا که چیست امید و سرور و تاج فخر ما؟ مگر شما نیستید در حضور خداوند ما عیسی درهنگام ظهور او؟"},{"v":20,"t":"زیرا که شما جلال و خوشی ما هستید."}],"en":[{"v":1,"t":"For you yourselves know, brothers, our visit to you wasn’t in vain,"},{"v":2,"t":"but having suffered before and been shamefully treated, as you know, at Philippi, we grew bold in our God to tell you the Good News of God in much conflict."},{"v":3,"t":"For our exhortation is not of error, nor of uncleanness, nor in deception."},{"v":4,"t":"But even as we have been approved by God to be entrusted with the Good News, so we speak—not as pleasing men, but God, who tests our hearts."},{"v":5,"t":"For neither were we at any time found using words of flattery, as you know, nor a cloak of covetousness (God is witness),"},{"v":6,"t":"nor seeking glory from men (neither from you nor from others), when we might have claimed authority as apostles of Christ."},{"v":7,"t":"But we were gentle among you, like a nursing mother cherishes her own children."},{"v":8,"t":"Even so, affectionately longing for you, we were well pleased to impart to you not the Good News of God only, but also our own souls, because you had become very dear to us."},{"v":9,"t":"For you remember, brothers, our labor and travail; for working night and day, that we might not burden any of you, we preached to you the Good News of God."},{"v":10,"t":"You are witnesses with God how holy, righteously, and blamelessly we behaved ourselves toward you who believe."},{"v":11,"t":"As you know, we exhorted, comforted, and implored every one of you, as a father does his own children,"},{"v":12,"t":"to the end that you should walk worthily of God, who calls you into his own Kingdom and glory."},{"v":13,"t":"For this cause we also thank God without ceasing that when you received from us the word of the message of God, you accepted it not as the word of men, but as it is in truth, God’s word, which also works in you who believe."},{"v":14,"t":"For you, brothers, became imitators of the assemblies of God which are in Judea in Christ Jesus; for you also suffered the same things from your own countrymen, even as they did from the Jews"},{"v":15,"t":"who killed both the Lord Jesus and their own prophets, and drove us out, and don’t please God, and are contrary to all men,"},{"v":16,"t":"forbidding us to speak to the Gentiles that they may be saved, to fill up their sins always. But wrath has come on them to the uttermost."},{"v":17,"t":"But we, brothers, being bereaved of you for a short season in presence, not in heart, tried even harder to see your face with great desire,"},{"v":18,"t":"because we wanted to come to you—indeed, I, Paul, once and again—but Satan hindered us."},{"v":19,"t":"For what is our hope, or joy, or crown of rejoicing? Isn’t it even you, before our Lord Jesus at his coming?"},{"v":20,"t":"For you are our glory and our joy."}],"hr":[{"v":1,"t":"Sami doista znate, braćo: naš dolazak k vama nije bio uzaludan."},{"v":2,"t":"Naprotiv, i pošto smo, kako znate, u Filipima trpjeli i bili pogrđeni, odvažismo se u Bogu našemu iznijeti vam, uz tešku borbu, evanđelje Božje."},{"v":3,"t":"Uistinu, naše poticanje ne proistječe iz zablude, ni nečistoće, ni prijevare,"},{"v":4,"t":"nego kako je Bog prosudio povjeriti nam evanđelje, tako ga i navješćujemo - ne kao da želimo ugoditi ljudima, nego Bogu koji prosuđuje srca naša."},{"v":5,"t":"Nikada se zaista kako znate, ne poslužismo ni laskavom riječju ni - Bog nam je svjedok - prikrivenom pohlepom."},{"v":6,"t":"Niti smo od ljudi iskali slavu - ni od vas, ni od drugih -"},{"v":7,"t":"premda smo se mogli nametnuti kao Kristovi apostoli. Ali bili smo među vama nježni kao majka što hrani i njeguje svoju djecu."},{"v":8,"t":"Tako, puni ljubavi prema vama, htjedosmo vam predati ne samo evanđelje Božje nego i naše duše jer ste nam omiljeli."},{"v":9,"t":"Sjećate se doista, braćo, našega truda i napora. Propovijedali smo vam evanđelje Božje i radili noću i danju da ne bismo opteretili koga od vas."},{"v":10,"t":"Svjedoci ste vi i Bog kako smo se sveto, pravedno i besprijekorno vladali prema vama, vjernicima."},{"v":11,"t":"Kao što znate, svakoga smo od vas kao otac svoju djecu,"},{"v":12,"t":"poticali, sokolili i zaklinjali da živite dostojno Boga koji vas pozva u svoje kraljevstvo i slavu."},{"v":13,"t":"Zato, eto, i mi bez prestanka zahvaljujemo Bogu što ste, kad od nas primiste riječ poruke Božje, primili ne riječ ljudsku, nego kakva uistinu jest, riječ Božju koja i djeluje u vama, vjernicima."},{"v":14,"t":"Doista, vi ste, braćo, postali nasljedovatelji crkava Božjih koje su u Judeji u Kristu Isusu: i vi isto trpite od svojih suplemenika što i oni od Židova,"},{"v":15,"t":"koji su i Gospodina Isusa i proroke ubili, i nas progonili, te Bogu ne ugađaju i svim se ljudima protive"},{"v":16,"t":"kad nam priječe propovijedati poganima da se spase, da bi tako u svako vrijeme navršili mjeru zlodjela svojih. Ali sručio se na njih konačni gnjev."},{"v":17,"t":"A mi, braćo, pošto smo za kratko vrijeme ostali bez vas - licem, ne srcem - brže se bolje, u silnoj čežnji, požurismo ugledati vaše lice."},{"v":18,"t":"Zaista, htjedosmo k vama - ja, Pavao, i jednom i dvaput - ali nas je spriječio Sotona."},{"v":19,"t":"Ta tko li će biti naša nada, radost ili vijenac dični - zar možda ne i vi? - pred Gospodinom našim Isusom o njegovu Dolasku?"},{"v":20,"t":"Vi ste doista slava naša i radost!"}]},"3":{"fa":[{"v":1,"t":"پس چون دیگر شکیبایی نداشتیم، رضابدین دادیم که ما را در اتینا تنها واگذاردند."},{"v":2,"t":"و تیموتاوس را که برادر ما و خادم خدا درانجیل مسیح است، فرستادیم تا شما را استوارسازد و در خصوص ایمانتان شما را نصیحت کند."},{"v":3,"t":"تا هیچ‌کس از این مصائب متزلزل نشود، زیراخود می‌دانید که برای همین مقرر شده‌ایم."},{"v":4,"t":"زیراهنگامی که نزد شما بودیم، شما را پیش خبردادیم که می‌باید زحمت بکشیم، چنانکه واقع شدو می‌دانید."},{"v":5,"t":"لهذا من نیز چون شکیبایی نداشتم، فرستادم تا ایمان شما را تحقیق کنم مبادا که آن تجربه کننده، شما را تجربه کرده باشد و محنت ماباطل گردد."},{"v":6,"t":"اما الحال چون تیموتاوس از نزد شما به مارسید و مژده ایمان و محبت شما را به ما رسانید واینکه شما پیوسته ما را نیکو یاد می‌کنید و مشتاق ملاقات ما می‌باشید، چنانکه ما نیز شایق شماهستیم،"},{"v":7,"t":"لهذا‌ای برادران، در همه ضیق ومصیبتی که داریم، از شما به‌سبب ایمانتان تسلی یافتیم."},{"v":8,"t":"چونکه الان زیست می‌کنیم، اگر شما درخداوند استوار هستید."},{"v":9,"t":"زیرا چه شکرگزاری به خدا توانیم نمود به‌سبب این همه خوشی‌ای که به حضور خدا درباره شما داریم؛"},{"v":10,"t":"که شبانه‌روزبی شمار دعا می‌کنیم تا شما را روبرو ملاقات کنیم و نقص ایمان شما را به‌کمال رسانیم."},{"v":11,"t":"اماخود خدا یعنی پدر ما و خداوند ما عیسی مسیح راه ما را به سوی شما راست بیاورد."},{"v":12,"t":"و خداوندشما را نمو دهد و درمحبت با یکدیگر و با همه افزونی بخشد، چنانکه ما شما را محبت می‌نماییم،"},{"v":13,"t":"تا دلهای شما را استوار سازد، بی‌عیب در قدوسیت، به حضور خدا و پدر ما درهنگام ظهور خداوند ما عیسی مسیح، با جمیع مقدسین خود."}],"en":[{"v":1,"t":"Therefore when we couldn’t stand it any longer, we thought it good to be left behind at Athens alone,"},{"v":2,"t":"and sent Timothy, our brother and God’s servant in the Good News of Christ, to establish you and to comfort you concerning your faith,"},{"v":3,"t":"that no one would be moved by these afflictions. For you know that we are appointed to this task."},{"v":4,"t":"For most certainly, when we were with you, we told you beforehand that we are to suffer affliction, even as it happened, and you know."},{"v":5,"t":"For this cause I also, when I couldn’t stand it any longer, sent that I might know your faith, for fear that by any means the tempter had tempted you, and our labor would have been in vain."},{"v":6,"t":"But Timothy has just now come to us from you, and brought us glad news of your faith and love, and that you have good memories of us always, longing to see us, even as we also long to see you."},{"v":7,"t":"For this cause, brothers, we were comforted over you in all our distress and affliction through your faith."},{"v":8,"t":"For now we live, if you stand fast in the Lord."},{"v":9,"t":"For what thanksgiving can we render again to God for you, for all the joy with which we rejoice for your sakes before our God,"},{"v":10,"t":"night and day praying exceedingly that we may see your face and may perfect that which is lacking in your faith?"},{"v":11,"t":"Now may our God and Father himself, and our Lord Jesus Christ, direct our way to you."},{"v":12,"t":"May the Lord make you to increase and abound in love toward one another and toward all men, even as we also do toward you,"},{"v":13,"t":"to the end he may establish your hearts blameless in holiness before our God and Father at the coming of our Lord Jesus with all his saints."}],"hr":[{"v":1,"t":"Zato kad više ne mogosmo izdržati, pristadosmo ostati u Ateni sami"},{"v":2,"t":"te poslasmo Timoteja, brata našega i suradnika Božjega u Kristovu evanđelju, da vas učvrsti i ohrabri u vjeri"},{"v":3,"t":"da se nitko ne pokoleba u tim nevoljama. Ta i sami znate da smo za to određeni:"},{"v":4,"t":"doista, kad smo bili kod vas, pretkazivali smo kako nas imaju zadesiti nevolje, što se, kako znate, i dogodilo."},{"v":5,"t":"Zbog toga i ja, ne mogavši više izdržati, poslah da saznam o vašoj vjeri, da vas možda Zavodnik nije zaveo te je naš trud postao uzaludan."},{"v":6,"t":"A sada kad se Timotej od vas k nama vratio i donio nam radosnu vijest o vašoj vjeri i ljubavi, i da nas se sveudilj ugodno sjećate i čeznete vidjeti nas, kao i mi vas -"},{"v":7,"t":"zbog toga smo, braćo, nad vama, vašom vjerom, bili utješeni uza svu svoju tjeskobu i nevolju."},{"v":8,"t":"Da, sada živimo kada ste vi postojani u Gospodinu!"},{"v":9,"t":"I kojom bismo zahvalom mogli Bogu uzvratiti za vas, za svu radost kojom se zbog vas radujemo pred Bogom svojim,"},{"v":10,"t":"dok noću i danju najusrdnije molimo da vidimo vaše lice i nadoknadimo manjkavosti vaše vjere?"},{"v":11,"t":"A sam Bog i Otac naš i Gospodin naš Isus upravio naš put prema vama!"},{"v":12,"t":"Vama pak Gospodin dao te jedni prema drugima i prema svima rasli i obilovali ljubavlju kakva je i naša prema vama."},{"v":13,"t":"Učvrstio vam srca da budu besprijekorno sveta pred Bogom i Ocem našim o Dolasku Gospodina našega Isusa i svih svetih njegovih s njime."}]},"4":{"fa":[{"v":1,"t":"خلاصه‌ای برادران، از شما در عیسی خداوند استدعا و التماس می‌کنیم که چنانکه از ما یافته‌اید که به چه نوع باید رفتار کنیدو خدا را راضی سازید، به همانطور زیادتر ترقی نمایید."},{"v":2,"t":"زیرا می‌دانید چه احکام از جانب عیسی خداوند به شما دادیم."},{"v":3,"t":"زیرا که این است اراده خدا یعنی قدوسیت شما تا از زنا بپرهیزید."},{"v":4,"t":"تاهرکسی از شما بداند چگونه باید ظرف خویشتن را در قدوسیت و عزت دریابد،"},{"v":5,"t":"و نه در هوس شهوت، مثل امت هایی که خدا را نمی شناسند."},{"v":6,"t":"و تا کسی در این امر دست تطاول یا طمع بر برادر خود دراز نکند، زیرا خداوند از تمامی چنین کارها انتقام کشنده است."},{"v":7,"t":"چنانکه سابق نیز به شما گفته و حکم کرده‌ایم، زیرا خدا ما را به ناپاکی نخوانده است، بلکه به قدوسیت."},{"v":8,"t":"لهذا هرکه حقیر شمارد، انسان را حقیر نمی شمارد، بلکه خدا را که روح قدوس خود را به شما عطا کرده است."},{"v":9,"t":"اما در خصوص محبت برادرانه، لازم نیست که به شما بنویسم، زیرا خود شما از خدا آموخته شده‌اید که یکدیگر را محبت نمایید؛"},{"v":10,"t":"و چنین هم می‌کنید با همه برادرانی که در تمام مکادونیه می‌باشند. لیکن‌ای برادران از شما التماس داریم که زیادتر ترقی کنید."},{"v":11,"t":"و حریص باشید در اینکه آرام شوید و به‌کارهای خود مشغول شده، به‌دستهای خویش کسب نمایید، چنانکه شما راحکم کردیم،"},{"v":12,"t":"تا نزد آنانی که خارج‌اند بطورشایسته رفتار کنید و به هیچ‌چیز محتاج نباشید."},{"v":13,"t":"اما‌ای برادران نمی خواهیم شما از حالت خوابیدگان بی‌خبر باشید که مبادا مثل دیگران که امید ندارند، محزون شوید."},{"v":14,"t":"زیرا اگر باورمی کنیم که عیسی مرد و برخاست، به همینطورنیز خدا آنانی را که در عیسی خوابیده‌اند با وی خواهد آورد."},{"v":15,"t":"زیرا این را به شما از کلام خدامی گوییم که ما که زنده و تا آمدن خداوند باقی باشیم برخوابیدگان سبقت نخواهیم جست."},{"v":16,"t":"زیرا خود خداوند با صدا و با آواز رئیس فرشتگان و با صور خدا از آسمان نازل خواهدشد و مردگان در مسیح اول خواهند برخاست."},{"v":17,"t":"آنگاه ما که زنده و باقی باشیم، با ایشان در ابرهاربوده خواهیم شد تا خداوند را در هوا استقبال کنیم و همچنین همیشه با خداوند خواهیم بود."},{"v":18,"t":"پس بدین سخنان همدیگر را تسلی دهید."}],"en":[{"v":1,"t":"Finally then, brothers, we beg and exhort you in the Lord Jesus, that as you received from us how you ought to walk and to please God, that you abound more and more."},{"v":2,"t":"For you know what instructions we gave you through the Lord Jesus."},{"v":3,"t":"For this is the will of God: your sanctification, that you abstain from sexual immorality,"},{"v":4,"t":"that each one of you know how to control his own body in sanctification and honor,"},{"v":5,"t":"not in the passion of lust, even as the Gentiles who don’t know God,"},{"v":6,"t":"that no one should take advantage of and wrong a brother or sister in this matter; because the Lord is an avenger in all these things, as also we forewarned you and testified."},{"v":7,"t":"For God called us not for uncleanness, but in sanctification."},{"v":8,"t":"Therefore he who rejects this doesn’t reject man, but God, who has also given his Holy Spirit to you."},{"v":9,"t":"But concerning brotherly love, you have no need that one write to you. For you yourselves are taught by God to love one another,"},{"v":10,"t":"for indeed you do it toward all the brothers who are in all Macedonia. But we exhort you, brothers, that you abound more and more;"},{"v":11,"t":"and that you make it your ambition to lead a quiet life, and to do your own business, and to work with your own hands, even as we instructed you,"},{"v":12,"t":"that you may walk properly toward those who are outside, and may have need of nothing."},{"v":13,"t":"But we don’t want you to be ignorant, brothers, concerning those who have fallen asleep, so that you don’t grieve like the rest, who have no hope."},{"v":14,"t":"For if we believe that Jesus died and rose again, even so God will bring with him those who have fallen asleep in Jesus."},{"v":15,"t":"For this we tell you by the word of the Lord, that we who are alive, who are left until the coming of the Lord, will in no way precede those who have fallen asleep."},{"v":16,"t":"For the Lord himself will descend from heaven with a shout, with the voice of the archangel and with God’s trumpet. The dead in Christ will rise first,"},{"v":17,"t":"then we who are alive, who are left, will be caught up together with them in the clouds to meet the Lord in the air. So we will be with the Lord forever."},{"v":18,"t":"Therefore comfort one another with these words."}],"hr":[{"v":1,"t":"Uostalom, braćo, molimo vas i zaklinjemo u Gospodinu Isusu: primili ste od nas kako treba da živite da biste ugodili Bogu. Vi tako i živite pa sve više napredujete!"},{"v":2,"t":"Ta znate koje smo vam zapovijedi dali u Gospodinu Isusu."},{"v":3,"t":"Doista, ovo je volja Božja: vaše posvećenje - da se uzdržavate od bludnosti,"},{"v":4,"t":"da svatko od vas zna svoje tijelo posjedovati u svetosti i poštovanju,"},{"v":5,"t":"a ne u pohotnoj strasti kao pogani koji ne poznaju Boga,"},{"v":6,"t":"pa time ne prikraćivati i varati svoga brata. Jer Gospodin je osvetnik za sve to, kao što vam već rekosmo i posvjedočismo."},{"v":7,"t":"Bog nas, doista, nije pozvao na nečistoću, nego na svetost."},{"v":8,"t":"Prema tome, tko to odbacuje, ne odbacuje čovjeka nego Boga koji svoga Duha Svetoga udahnjuje u vas."},{"v":9,"t":"A o bratoljublju vam nije potrebno pisati. Ta i sami ste od Boga naučili ljubiti jedni druge,"},{"v":10,"t":"a to doista i činite prema svoj braći u cijeloj Makedoniji. Samo vas, braćo, potičemo da u tom još više uznapredujete"},{"v":11,"t":"pa da se trsite mirno živjeti, svoje činiti i raditi svojim rukama, kako smo vam zapovijedili,"},{"v":12,"t":"te tako časno živite prema onima vani i nikoga ne trebate."},{"v":13,"t":"Nećemo da budete u neznanju, braćo, o onima koji su usnuli, da ne tugujete kao drugi koji nemaju nade."},{"v":14,"t":"Doista, ako vjerujemo da je Isus umro i uskrsnuo, onda će Bog i one koji usnuše u Isusu, privesti zajedno s njime."},{"v":15,"t":"Ovo vam uistinu velimo po riječi Gospodnjoj: mi živi, preostali za Dolazak Gospodnji, nećemo preteći onih koji su usnuli."},{"v":16,"t":"Jer sam će Gospodin - na zapovijed, na glas arkanđelov, na zov trublje Božje - sići s neba. I najprije će uskrsnuti mrtvi u Kristu,"},{"v":17,"t":"a zatim ćemo mi živi, preostali, zajedno s njima biti poneseni na oblacima u susret Gospodinu, u zrak. I tako ćemo uvijek biti s Gospodinom."},{"v":18,"t":"Tješite se dakle uzajamno ovim riječima!"}]},"5":{"fa":[{"v":1,"t":"اما‌ای برادران در خصوص وقتها و زمانها، احتیاج ندارید که به شما بنویسم."},{"v":2,"t":"زیراخود شما به تحقیق آگاهید که روز خداوند چون دزد در شب می‌آید."},{"v":3,"t":"زیرا هنگامی که می‌گویندسلامتی و امان است، آنگاه هلاکت ایشان راناگهان فرو خواهد گرفت، چون درد زه زن حامله را و هرگز رستگار نخواهند شد."},{"v":4,"t":"لیکن شما‌ای برادران در ظلمت نیستید تا آن روز چون دزد برشما آید،"},{"v":5,"t":"زیرا جمیع شما پسران نور و پسران روز هستید، از شب و ظلمت نیستیم."},{"v":6,"t":"بنابراین مثل دیگران به خواب نرویم بلکه بیدار و هشیارباشیم."},{"v":7,"t":"زیرا خوابیدگان در شب می‌خوابند ومستان در شب مست می‌شوند."},{"v":8,"t":"لیکن ما که ازروز هستیم، هشیار بوده، جوشن ایمان و محبت وخود امید نجات را بپوشیم."},{"v":9,"t":"زیرا خدا ما را تعیین نکرد برای غضب بلکه بجهت تحصیل نجات، بوسیله خداوند ما عیسی مسیح،"},{"v":10,"t":"که برای مامرد تا خواه بیدار باشیم و خواه خوابیده، همراه وی زیست کنیم."},{"v":11,"t":"پس همدیگر را تسلی دهیدو یکدیگر را بنا کنید، چنانکه هم می‌کنید."},{"v":12,"t":"اما‌ای برادران به شما التماس داریم که بشناسید آنانی را که در میان شما زحمت می‌کشند و پیشوایان شما در خداوند بوده، شمارا نصیحت می‌کنند."},{"v":13,"t":"و ایشان را در نهایت محبت، به‌سبب عملشان محترم دارید و بایکدیگر صلح کنید."},{"v":14,"t":"لیکن‌ای برادران، از شمااستدعا داریم که سرکشان را تنبیه نمایید وکوتاه دلان را دلداری دهید و ضعفا را حمایت کنید و با جمیع مردم تحمل کنید."},{"v":15,"t":"زنهار کسی با کسی به سزای بدی بدی نکند، بلکه دائم بایکدیگر و با جمیع مردم در‌پی نیکویی بکوشید."},{"v":16,"t":"پیوسته شادمان باشید."},{"v":17,"t":"همیشه دعا کنید."},{"v":18,"t":"در هر امری شاکر باشید که این است اراده خدادر حق شما در مسیح عیسی."},{"v":19,"t":"روح را اطفامکنید."},{"v":20,"t":"نبوتها را خوار مشمارید."},{"v":21,"t":"همه‌چیزرا تحقیق کنید، و به آنچه نیکو است متمسک باشید."},{"v":22,"t":"از هر نوع بدی احتراز نمایید."},{"v":23,"t":"اما خود خدای سلامتی، شما را بالکل مقدس گرداناد و روح و نفس و بدن شما تمام بی‌عیب محفوظ باشد در وقت آمدن خداوند ماعیسی مسیح."},{"v":24,"t":"امین است دعوت کننده شما که این را هم خواهد کرد."},{"v":25,"t":"‌ای برادران، برای ما دعا کنید."},{"v":26,"t":"جمیع برادران را به بوسه مقدسانه تحیت نمایید."},{"v":27,"t":"شمارا به خداوند قسم می‌دهم که این رساله برای جمیع برادران مقدس خوانده شود."},{"v":28,"t":"فیض خداوند ما عیسی مسیح با شما بادآمین."}],"en":[{"v":1,"t":"But concerning the times and the seasons, brothers, you have no need that anything be written to you."},{"v":2,"t":"For you yourselves know well that the day of the Lord comes like a thief in the night."},{"v":3,"t":"For when they are saying, “Peace and safety,” then sudden destruction will come on them, like birth pains on a pregnant woman. Then they will in no way escape."},{"v":4,"t":"But you, brothers, aren’t in darkness, that the day should overtake you like a thief."},{"v":5,"t":"You are all children of light and children of the day. We don’t belong to the night, nor to darkness,"},{"v":6,"t":"so then let’s not sleep, as the rest do, but let’s watch and be sober."},{"v":7,"t":"For those who sleep, sleep in the night; and those who are drunk are drunk in the night."},{"v":8,"t":"But since we belong to the day, let’s be sober, putting on the breastplate of faith and love, and for a helmet, the hope of salvation."},{"v":9,"t":"For God didn’t appoint us to wrath, but to the obtaining of salvation through our Lord Jesus Christ,"},{"v":10,"t":"who died for us, that, whether we wake or sleep, we should live together with him."},{"v":11,"t":"Therefore exhort one another, and build each other up, even as you also do."},{"v":12,"t":"But we beg you, brothers, to know those who labor among you, and are over you in the Lord and admonish you,"},{"v":13,"t":"and to respect and honor them in love for their work’s sake. Be at peace among yourselves."},{"v":14,"t":"We exhort you, brothers: Admonish the disorderly; encourage the faint-hearted; support the weak; be patient toward all."},{"v":15,"t":"See that no one returns evil for evil to anyone, but always follow after that which is good for one another and for all."},{"v":16,"t":"Always rejoice."},{"v":17,"t":"Pray without ceasing."},{"v":18,"t":"In everything give thanks, for this is the will of God in Christ Jesus toward you."},{"v":19,"t":"Don’t quench the Spirit."},{"v":20,"t":"Don’t despise prophecies."},{"v":21,"t":"Test all things, and hold firmly that which is good."},{"v":22,"t":"Abstain from every form of evil."},{"v":23,"t":"May the God of peace himself sanctify you completely. May your whole spirit, soul, and body be preserved blameless at the coming of our Lord Jesus Christ."},{"v":24,"t":"He who calls you is faithful, who will also do it."},{"v":25,"t":"Brothers, pray for us."},{"v":26,"t":"Greet all the brothers with a holy kiss."},{"v":27,"t":"I solemnly command you by the Lord that this letter be read to all the holy brothers."},{"v":28,"t":"The grace of our Lord Jesus Christ be with you. Amen."}],"hr":[{"v":1,"t":"A o vremenima i trenucima nije, braćo, potrebno pisati vam."},{"v":2,"t":"Ta i sami dobro znate da Dan Gospodnji dolazi baš kao kradljivac u noći."},{"v":3,"t":"Dok još budu govorili: “Mir i sigurnost”, zadesit će ih iznenadna propast kao trudovi trudnicu i neće umaći."},{"v":4,"t":"Ali vi, braćo, niste u tami, da bi vas Dan mogao zaskočiti kao kradljivac:"},{"v":5,"t":"ta svi ste vi sinovi svjetlosti i sinovi dana. Nismo doista od noći ni od tame."},{"v":6,"t":"Onda i ne spavajmo kao ostali, nego bdijmo i trijezni budimo."},{"v":7,"t":"Jer koji spavaju, noću spavaju; i koji se opijaju, noću se opijaju."},{"v":8,"t":"A mi koji smo od dana, budimo trijezni, obucimo oklop vjere i ljubavi i stavimo kacigu, nadu spasenja!"},{"v":9,"t":"Ta Bog nas nije odredio za gnjev, nego da imamo spasenje po Gospodinu našem Isusu Kristu,"},{"v":10,"t":"koji je za nas umro da - bdjeli ili spavali - zajedno s njime živimo."},{"v":11,"t":"Zato, tješite se uzajamno i izgrađujte jedan drugoga, kako i činite."},{"v":12,"t":"Molimo vas, braćo: priznajte one koji se trude među vama, koji su vam predstojnici u Gospodinu i opominju vas;"},{"v":13,"t":"s ljubavlju ih nadasve cijenite poradi njihova djela! Gajite mir među sobom!"},{"v":14,"t":"Potičemo vas, braćo: opominjite neuredne, sokolite malodušne, podržavajte slabe, budite velikodušni prema svima!"},{"v":15,"t":"Pazite da tko komu zlo zlom ne uzvrati, nego uvijek promičite dobro jedni prema drugima i prema svima."},{"v":16,"t":"Uvijek se radujte!"},{"v":17,"t":"Bez prestanka se molite!"},{"v":18,"t":"U svemu zahvaljujte! Jer to je za vas volja Božja u Kristu Isusu."},{"v":19,"t":"Duha ne trnite,"},{"v":20,"t":"proroštava ne prezirite!"},{"v":21,"t":"Sve provjeravajte: dobro zadržite,"},{"v":22,"t":"svake se sjene zla klonite!"},{"v":23,"t":"A sam Bog mira neka vas posvema posveti i cijelo vaše biće - duh vaš i duša i tijelo - neka se besprijekornim, savršenim sačuva za Dolazak Gospodina našega Isusa Krista."},{"v":24,"t":"Vjeran je Onaj tko vas poziva: on će to i učiniti."},{"v":25,"t":"Braćo, molite i za nas!"},{"v":26,"t":"Pozdravite svu braću cjelovom svetim."},{"v":27,"t":"Zaklinjem vas u Gospodinu: neka se ova poslanica pročita svoj braći."},{"v":28,"t":"Milost Gospodina našega Isusa Krista s vama!"}]}},"2TH":{"1":{"fa":[{"v":1,"t":"پولس و سلوانس و تیموتاوس، به کلیسای تسالونیکیان که در خدای پدر ماو عیسی مسیح خداوند می‌باشید."},{"v":2,"t":"فیض و سلامتی از جانب پدر ما خدا وعیسی مسیح خداوند بر شما باد."},{"v":3,"t":"‌ای برادران می‌باید همیشه بجهت شما خدارا شکر کنیم، چنانکه سزاوار است، از آنجا که ایمان شما بغایت نمو می‌کند و محبت هر یکی ازشما جمیع با همدیگر می‌افزاید،"},{"v":4,"t":"بحدی که خود ما در خصوص شما در کلیساهای خدا فخرمی کنیم به‌سبب صبر و ایمانتان در همه مصایب شما و عذابهایی که متحمل آنها می‌شوید،"},{"v":5,"t":"که دلیل است بر داوری عادل خدا تا شما مستحق ملکوت خدا بشوید که برای آن هم زحمت می‌کشید."},{"v":6,"t":"زیرا که این انصاف است نزد خدا که عذاب کنندگان شما را عذاب دهد."},{"v":7,"t":"و شما را که عذاب می‌کشید، با ما راحت بخشد در هنگامی که عیسی خداوند از آسمان با فرشتگان قوت خودظهور خواهد نمود"},{"v":8,"t":"در آتش مشتعل و انتقام خواهد کشید از آنانی که خدا را نمی شناسند وانجیل خداوند ما عیسی مسیح را اطاعت نمی کنند،"},{"v":9,"t":"که ایشان به قصاص هلاکت جاودانی خواهند رسید از حضور خداوند و جلال قوت او"},{"v":10,"t":"هنگامی که آید تا در مقدسان خود جلال یابدو در همه ایمانداران از او تعجب کنند در آن روز، زیرا که شما شهادت ما را تصدیق کردید."},{"v":11,"t":"و برای این هم پیوسته بجهت شما دعامی کنیم که خدای ما شما را مستحق این دعوت شمارد و تمام مسرت نیکویی و عمل ایمان را باقوت کامل گرداند،"},{"v":12,"t":"تا نام خداوند ما عیسی مسیح در شما تمجید یابد و شما در وی بحسب فیض خدای ما و عیسی مسیح خداوند."}],"en":[{"v":1,"t":"Paul, Silvanus, and Timothy, to the assembly of the Thessalonians in God our Father and the Lord Jesus Christ:"},{"v":2,"t":"Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":3,"t":"We are bound to always give thanks to God for you, brothers, even as it is appropriate, because your faith grows exceedingly, and the love of each and every one of you toward one another abounds,"},{"v":4,"t":"so that we ourselves boast about you in the assemblies of God for your perseverance and faith in all your persecutions and in the afflictions which you endure."},{"v":5,"t":"This is an obvious sign of the righteous judgment of God, to the end that you may be counted worthy of God’s Kingdom, for which you also suffer."},{"v":6,"t":"For it is a righteous thing with God to repay affliction to those who afflict you,"},{"v":7,"t":"and to give relief to you who are afflicted with us when the Lord Jesus is revealed from heaven with his mighty angels in flaming fire,"},{"v":8,"t":"punishing those who don’t know God, and to those who don’t obey the Good News of our Lord Jesus,"},{"v":9,"t":"who will pay the penalty: eternal destruction from the face of the Lord and from the glory of his might,"},{"v":10,"t":"when he comes in that day to be glorified in his saints and to be admired among all those who have believed, because our testimony to you was believed."},{"v":11,"t":"To this end we also pray always for you that our God may count you worthy of your calling, and fulfill every desire of goodness and work of faith with power,"},{"v":12,"t":"that the name of our Lord Jesus may be glorified in you, and you in him, according to the grace of our God and the Lord Jesus Christ."}],"hr":[{"v":1,"t":"Pavao, Silvan i Timotej Crkvi Solunjana u Bogu Ocu našemu i Gospodinu Isusu Kristu."},{"v":2,"t":"Milost vam i mir od Boga Oca i Gospodina Isusa Krista!"},{"v":3,"t":"Zahvaljivati moramo Bogu uvijek za vas, braćo, kao što dolikuje jer izvanredno raste vaša vjera i množi se ljubav svakoga od vas prema drugima,"},{"v":4,"t":"tako da se mi sami po crkvama Božjim vama ponosimo zbog vaše postojanosti i vjere u svim progonstvima i nevoljama koje podnosite."},{"v":5,"t":"One su najava pravednog Suda Božjega: da ćete se naći dostojni kraljevstva Božjega za koje i trpite."},{"v":6,"t":"Jer pravo je da Bog vašim mučiteljima mukom,"},{"v":7,"t":"a vama, mučenima, zajedno s nama spokojem uzvrati kad se Gospodin Isus objavi s nama, zajedno s anđelima svoje moći,"},{"v":8,"t":"u ognju žarkome i osveti se onima koji ne poznaju Boga i ne pokoravaju se evanđelju Gospodina našega Isusa."},{"v":9,"t":"Oni će biti kažnjeni vječnom propašću, daleko od lica Gospodnjega i od slave njegova veličanstva,"},{"v":10,"t":"kada - u onaj Dan - dođe da se proslavi u svojim svetima i da se prodiči u svima koji povjerovaše. Jer povjerovalo se svjedočanstvu našemu među vama."},{"v":11,"t":"Zato i molimo uvijek za vas da vas Bog učini dostojnima poziva i snažno dovede do punine svako vaše nastojanje oko dobra i djelo vaše vjere"},{"v":12,"t":"te da se proslavi ime Gospodina našega Isusa u vama i vi u njemu - po milosti Boga našega i Gospodina Isusa Krista."}]},"2":{"fa":[{"v":1,"t":"اما‌ای برادران، از شما استدعا می‌کنیم درباره آمدن خداوند ما عیسی مسیح وجمع شدن ما به نزد او،"},{"v":2,"t":"که شما از هوش خودبزودی متزلزل نشوید و مضطرب نگردید، نه ازروح و نه از کلام و نه از رساله‌ای که گویا از ماباشد، بدین مضمون که روز مسیح رسیده است."},{"v":3,"t":"زنهار کسی به هیچ وجه شما را نفریبد، زیرا که تاآن ارتداد، اول واقع نشود و آن مرد شریر یعنی فرزند هلاکت ظاهر نگردد، آن روز نخواهد آمد؛"},{"v":4,"t":"که او مخالفت می‌کند و خود را بلندتر می‌سازداز هر‌چه به خدا یا به معبود مسمی شود، بحدی که مثل خدا در هیکل خدا نشسته، خود را می نماید که خداست."},{"v":5,"t":"آیا یاد نمی کنید که هنگامی که هنوز نزد شمامی بودم، این را به شما می‌گفتم؟"},{"v":6,"t":"و الان آنچه راکه مانع است می‌دانید تا او در زمان خود ظاهربشود."},{"v":7,"t":"زیرا که آن سر بی‌دینی الان عمل می‌کندفقط تا وقتی که آنکه تا به حال مانع است از میان برداشته شود."},{"v":8,"t":"آنگاه آن بی‌دین ظاهر خواهد شدکه عیسی خداوند او را به نفس دهان خود هلاک خواهد کرد و به تجلی ظهور خویش، او را نابودخواهد ساخت؛"},{"v":9,"t":"که ظهور او بعمل شیطان است با هر نوع قوت و آیات و عجایب دروغ"},{"v":10,"t":"و به هرقسم فریب ناراستی برای هالکین، از آنجا که محبت راستی را نپذیرفتند تا نجات یابند."},{"v":11,"t":"وبدین جهت خدا به ایشان عمل گمراهی می‌فرستد تا دروغ را باور کنند"},{"v":12,"t":"و تا فتوایی شود بر همه کسانی که راستی را باور نکردند بلکه به ناراستی شاد شدند."},{"v":13,"t":"اما‌ای برادران و‌ای عزیزان خداوند، می‌باید ما همیشه برای شما خدا را شکر نماییم که از ابتدا خدا شما را برگزید برای نجات به تقدیس روح و ایمان به راستی."},{"v":14,"t":"و برای آن شمارا دعوت کرد بوسیله بشارت ما برای تحصیل جلال خداوند ما عیسی مسیح."},{"v":15,"t":"پس‌ای برادران، استوار باشید و آن روایات را که خواه ازکلام و خواه از رساله ما آموخته‌اید، نگاه دارید."},{"v":16,"t":"و خود خداوند ما عیسی مسیح و خدا و پدر ماکه ما را محبت نمود و تسلی ابدی و امید نیکو رابه فیض خود به ما بخشید،"},{"v":17,"t":"دلهای شما راتسلی عطا کناد و شما را در هر فعل و قول نیکواستوار گرداناد."}],"en":[{"v":1,"t":"Now, brothers, concerning the coming of our Lord Jesus Christ and our gathering together to him, we ask you"},{"v":2,"t":"not to be quickly shaken in your mind or troubled, either by spirit or by word or by letter as if from us, saying that the day of Christ has already come."},{"v":3,"t":"Let no one deceive you in any way. For it will not be unless the rebellion comes first, and the man of sin is revealed, the son of destruction."},{"v":4,"t":"He opposes and exalts himself against all that is called God or that is worshiped, so that he sits as God in the temple of God, setting himself up as God."},{"v":5,"t":"Don’t you remember that when I was still with you, I told you these things?"},{"v":6,"t":"Now you know what is restraining him, to the end that he may be revealed in his own season."},{"v":7,"t":"For the mystery of lawlessness already works. Only there is one who restrains now, until he is taken out of the way."},{"v":8,"t":"Then the lawless one will be revealed, whom the Lord will kill with the breath of his mouth and destroy by the manifestation of his coming;"},{"v":9,"t":"even he whose coming is according to the working of Satan with all power and signs and lying wonders,"},{"v":10,"t":"and with all deception of wickedness for those who are being lost, because they didn’t receive the love of the truth, that they might be saved."},{"v":11,"t":"Because of this, God sends them a powerful delusion, that they should believe a lie,"},{"v":12,"t":"that they all might be judged who didn’t believe the truth, but had pleasure in unrighteousness."},{"v":13,"t":"But we are bound to always give thanks to God for you, brothers loved by the Lord, because God chose you from the beginning for salvation through sanctification of the Spirit and belief in the truth,"},{"v":14,"t":"to which he called you through our Good News, for the obtaining of the glory of our Lord Jesus Christ."},{"v":15,"t":"So then, brothers, stand firm and hold the traditions which you were taught by us, whether by word or by letter."},{"v":16,"t":"Now our Lord Jesus Christ himself, and God our Father, who loved us and gave us eternal comfort and good hope through grace,"},{"v":17,"t":"comfort your hearts and establish you in every good work and word."}],"hr":[{"v":1,"t":"A što se tiče Dolaska Gospodina našega Isusa Krista i našeg okupljanja oko njega, molimo vas, braćo:"},{"v":2,"t":"ne dajte se brzo pokolebati u svom shvaćanju niti uznemiriti ni nekim duhom, ni nekom riječju, ni nekim tobože našim pismom, kao da će sad-na Dan Gospodnji."},{"v":3,"t":"Neka vas nitko ne zavede ni na koji način. Jer ako prije ne dođe onaj otpad i ne otkrije se Čovjek bezakonja, Sin propasti,"},{"v":4,"t":"Protivnik, onaj koji uzdiže sebe protiv svega što se zove Bog ili svetinja, dotle da i u Božji hram zasjedne gradeći se Bogom..."},{"v":5,"t":"Ne sjećate li se, to sam vam govorio dok sam još bio među vama?"},{"v":6,"t":"I sada znate što ga zadržava da bi se pojavio tek u svoje vrijeme."},{"v":7,"t":"Doista, otajstvo bezakonja već je na djelu, samo ima tko da ga sada zadržava dok ne bude uklonjen."},{"v":8,"t":"Tada će se otkriti Bezakonik. Njega će Gospodin Isus pogubiti dahom usta i uništiti pojavkom Dolaska svoga -"},{"v":9,"t":"njega koji djelovanjem Sotoninim dolazi sa svom silom, lažnim znamenjima i čudesima"},{"v":10,"t":"i sa svim nepravednim zavaravanjem onih koji propadaju poradi toga što ne prihvatiše ljubavi prema istini da bi se spasili."},{"v":11,"t":"I zato im Bog šalje djelovanje zavodničko da povjeruju laži"},{"v":12,"t":"te budu osuđeni svi koji nisu povjerovali istini, nego su se odlučili za nepravednost."},{"v":13,"t":"Mi pak moramo uvijek zahvaljivati Bogu za vas, braćo od Gospodina ljubljena, što vas je od početka odabrao za spasenje, posvećenjem u Duhu i vjerom u istinu."},{"v":14,"t":"Da, na to vas pozva po našem evanđelju - na posjedovanje slave Gospodina našega Isusa Krista."},{"v":15,"t":"Stoga braćo, čvrsto stojte i držite se predaja u kojima ste poučeni bilo našom riječju, bilo pismom."},{"v":16,"t":"A sam Gospodin naš Isus Krist i Bog, Otac naš, koji nas uzljubi i koji nam po milosti dade trajno ohrabrenje i dobru nadu,"},{"v":17,"t":"neka ohrabri vaša srca i neka ih učvrsti u svakom dobru djelu i riječi!"}]},"3":{"fa":[{"v":1,"t":"خلاصه‌ای برادران، برای ما دعا کنید تاکلام خداوند جاری شود و جلال یابدچنانکه در میان شما نیز؛"},{"v":2,"t":"و تا از مردم ناشایسته شریر برهیم زیرا که همه را ایمان نیست."},{"v":3,"t":"اما امین است آن خداوندی که شما را استوار و از شریرمحفوظ خواهد ساخت."},{"v":4,"t":"اما بر شما در خداونداعتماد داریم که آنچه به شما امر کنیم، بعمل می‌آورید و نیز خواهید آورد."},{"v":5,"t":"و خداوند دلهای شما را به محبت خدا و به صبر مسیح هدایت کناد."},{"v":6,"t":"ولی‌ای برادران، شما را به نام خداوند خودعیسی مسیح حکم می‌کنیم که از هر برادری که بی‌نظم رفتار می‌کند و نه برحسب آن قانونی که ازما یافته‌اید، اجتناب نمایید."},{"v":7,"t":"زیرا خود آگاه هستید که به چه قسم به ما اقتدا می‌باید نمود، چونکه در میان شما بی‌نظم رفتار نکردیم،"},{"v":8,"t":"و نان هیچ‌کس را مفت نخوردیم بلکه به محنت ومشقت شبانه‌روز به‌کار مشغول می‌بودیم تا براحدی از شما بار ننهیم."},{"v":9,"t":"نه آنکه اختیار نداریم بلکه تا خود را نمونه برای شما سازیم تا به ما اقتدانمایید."},{"v":10,"t":"زیرا هنگامی که نزد شما هم می‌بودیم، این را به شما امر فرمودیم که اگر کسی خواهد کارنکند، خوراک هم نخورد."},{"v":11,"t":"زیرا شنیدیم که بعضی در میان شما بی‌نظم رفتار می‌کنند که کاری نمی کنند بلکه فضول هستند."},{"v":12,"t":"اما چنین اشخاص را در خداوند ما عیسی مسیح حکم ونصیحت می‌کنیم که به آرامی کار کرده، نان خود را بخورند."},{"v":13,"t":"اما شما‌ای برادران از نیکوکاری خسته خاطر مشوید."},{"v":14,"t":"ولی اگر کسی سخن ما رادر این رساله اطاعت نکند، بر او نشانه گذارید و باوی معاشرت مکنید تا شرمنده شود."},{"v":15,"t":"اما او رادشمن مشمارید بلکه چون برادر او را تنبیه کنید."},{"v":16,"t":"اما خود خداوند سلامتی شما را پیوسته درهر صورت، سلامتی عطا کناد و خداوند با همگی شما باد."},{"v":17,"t":"تحیت به‌دست من پولس که علامت در هر رساله است بدینطور می‌نویسم:"},{"v":18,"t":"فیض خداوند ما عیسی مسیح با جمیع شما باد. آمین."}],"en":[{"v":1,"t":"Finally, brothers, pray for us, that the word of the Lord may spread rapidly and be glorified, even as also with you,"},{"v":2,"t":"and that we may be delivered from unreasonable and evil men; for not all have faith."},{"v":3,"t":"But the Lord is faithful, who will establish you and guard you from the evil one."},{"v":4,"t":"We have confidence in the Lord concerning you, that you both do and will do the things we command."},{"v":5,"t":"May the Lord direct your hearts into God’s love and into the perseverance of Christ."},{"v":6,"t":"Now we command you, brothers, in the name of our Lord Jesus Christ, that you withdraw yourselves from every brother who walks in rebellion and not after the tradition which they received from us."},{"v":7,"t":"For you know how you ought to imitate us. For we didn’t behave ourselves rebelliously among you,"},{"v":8,"t":"neither did we eat bread from anyone’s hand without paying for it, but in labor and travail worked night and day, that we might not burden any of you."},{"v":9,"t":"This was not because we don’t have the right, but to make ourselves an example to you, that you should imitate us."},{"v":10,"t":"For even when we were with you, we commanded you this: “If anyone is not willing to work, don’t let him eat.”"},{"v":11,"t":"For we hear of some who walk among you in rebellion, who don’t work at all, but are busybodies."},{"v":12,"t":"Now those who are that way, we command and exhort in the Lord Jesus Christ, that they work with quietness and eat their own bread."},{"v":13,"t":"But you, brothers, don’t be weary in doing what is right."},{"v":14,"t":"If any man doesn’t obey our word in this letter, note that man and have no company with him, to the end that he may be ashamed."},{"v":15,"t":"Don’t count him as an enemy, but admonish him as a brother."},{"v":16,"t":"Now may the Lord of peace himself give you peace at all times in all ways. The Lord be with you all."},{"v":17,"t":"I, Paul, write this greeting with my own hand, which is the sign in every letter. This is how I write."},{"v":18,"t":"The grace of our Lord Jesus Christ be with you all. Amen."}],"hr":[{"v":1,"t":"Uostalom, molite, braćo, za nas da riječ Gospodnja trči i proslavlja se kao i u vas"},{"v":2,"t":"i da se oslobodimo nezgodnih i opakih ljudi. Jer nemaju svi vjere!"},{"v":3,"t":"Ali, vjeran je Gospodin koji će nas učvrstiti i sačuvati od Zloga."},{"v":4,"t":"A uzdamo se, u Gospodinu, u vas: da vršite i da ćete vršiti ono što vam zapovijedamo."},{"v":5,"t":"A Gospodin neka upravi srca vaša k ljubavi Božjoj i postojanosti Kristovoj."},{"v":6,"t":"Zapovijedamo vam, braćo, u ime Gospodina Isusa Krista da se klonite svakoga brata što živi neuredno i ne po predaji koju primiste od nas."},{"v":7,"t":"Ta sami znate kako nas treba nasljedovati. Jer dok bijasmo među vama, nismo živjeli neuredno:"},{"v":8,"t":"ničiji kruh nismo badava jeli, nego smo u trudu i naporu noću i danju radili da ne bismo opteretili koga od vas."},{"v":9,"t":"Ne što ne bismo imali prava, nego da vam sebe damo za uzor koji ćete nasljedovati."},{"v":10,"t":"Doista, dok bijasmo u vas, ovo vam zapovijedasmo: Tko neće da radi, neka i ne jede!"},{"v":11,"t":"A čujemo da neki od vas žive neuredno: ništa ne rade, nego dangube."},{"v":12,"t":"Takvima zapovijedamo i zaklinjemo ih u Gospodinu Isusu Kristu: neka s mirom rade i svoj kruh jedu."},{"v":13,"t":"Vama pak, braćo, neka ne dodija činiti dobro."},{"v":14,"t":"Ako li se tko ne pokorava našoj riječi u ovoj poslanici, zabilježite ga, ne drugujte s njime, da se postidi,"},{"v":15,"t":"ali ga ne smatrajte neprijateljem, nego ga urazumljujte kao brata."},{"v":16,"t":"A sam Gospodin mira dao vam mir zauvijek i na svaki način! Gospodin sa svima vama!"},{"v":17,"t":"Pozdrav mojom rukom, Pavlovom. Ovo je znak u svakoj poslanici: ovako pišem."},{"v":18,"t":"Milost Gospodina našega Isusa Krista sa svima vama!"}]}},"1TI":{"1":{"fa":[{"v":1,"t":"پولس، رسول عیسی مسیح به حکم نجات‌دهنده ما خدا و مسیح عیسی خداوند که امید ما است،"},{"v":2,"t":"به فرزند حقیقی خود در ایمان، تیموتاوس. فیض و رحم و سلامتی از جانب خدای پدر وخداوند ما مسیح عیسی بر تو باد."},{"v":3,"t":"چنانکه هنگامی که عازم مکادونیه بودم، به شما التماس نمودم که در افسس بمانی تا بعضی را امر کنی که تعلیمی دیگر ندهند،"},{"v":4,"t":"و افسانه‌ها ونسب نامه های نامتناهی را اصغا ننمایند که اینهامباحثات را نه آن تعمیر الهی را که در ایمان است پدید می‌آورد."},{"v":5,"t":"اما غایت حکم، محبت است ازدل پاک و ضمیر صالح و ایمان بی‌ریا."},{"v":6,"t":"که از این امور بعضی منحرف گشته به بیهوده‌گویی توجه نموده‌اند،"},{"v":7,"t":"و می‌خواهند معلمان شریعت بشوندو حال آنکه نمی فهمند آنچه می‌گویند و نه آنچه به تاکید اظهار می‌نمایند."},{"v":8,"t":"لیکن می‌دانیم که شریعت نیکو است اگرکسی آن را برحسب شریعت بکار برد."},{"v":9,"t":"و این بداند که شریعت بجهت عادل موضوع نمی شود، بلکه برای سرکشان و طاغیان و بی‌دینان وگناهکاران و ناپاکان و حرامکاران و قاتلان پدر و قاتلان مادر و قاتلان مردم"},{"v":10,"t":"و زانیان و لواطان ومردم دزدان و دروغ‌گویان و قسم دروغ خوران وبرای هر عمل دیگری که برخلاف تعلیم صحیح باشد،"},{"v":11,"t":"برحسب انجیل جلال خدای متبارک که به من سپرده شده است."},{"v":12,"t":"و شکر می‌کنم خداوند خود مسیح عیسی را که مرا تقویت داد، چونکه امین شمرده، به این خدمتم ممتاز فرمود،"},{"v":13,"t":"که سابق کفرگو و مضر وسقطگو بودم، لیکن رحم یافتم از آنرو که ازجهالت در بی‌ایمانی کردم."},{"v":14,"t":"اما فیض خداوندما بی‌نهایت افزود با‌ایمان و محبتی که در مسیح عیسی است."},{"v":15,"t":"این سخن امین است و لایق قبول تام که مسیح عیسی به‌دنیا آمد تا گناهکاران را نجات‌بخشد که من بزرگترین آنها هستم."},{"v":16,"t":"بلکه از این جهت بر من رحم شد تا اول درمن، مسیح عیسی کمال حلم را ظاهر سازد تا آنانی را که بجهت حیات جاودانی به وی ایمان خواهند‌آورد، نمونه باشم."},{"v":17,"t":"باری پادشاه سرمدی و باقی ونادیده را، خدای حکیم وحید را اکرام و جلال تاابدالاباد باد. آمین."},{"v":18,"t":"‌ای فرزند تیموتاوس، این وصیت را به تو می سپارم برحسب نبوتهایی که سابق بر تو شد تادر آنها جنگ نیکو کنی،"},{"v":19,"t":"و ایمان و ضمیرصالح را نگاه داری که بعضی این را از خود دورانداخته، مر ایمان را شکسته کشتی شدند."},{"v":20,"t":"که از آن جمله هیمیناوس و اسکندر می‌باشند که ایشان را به شیطان سپردم تا تادیب شده، دیگرکفر نگویند."}],"en":[{"v":1,"t":"Paul, an apostle of Jesus Christ according to the commandment of God our Savior and the Lord Jesus Christ our hope,"},{"v":2,"t":"to Timothy, my true child in faith: Grace, mercy, and peace from God our Father and Christ Jesus our Lord."},{"v":3,"t":"As I urged you when I was going into Macedonia, stay at Ephesus that you might command certain men not to teach a different doctrine,"},{"v":4,"t":"and not to pay attention to myths and endless genealogies, which cause disputes rather than God’s stewardship, which is in faith."},{"v":5,"t":"But the goal of this command is love from a pure heart, a good conscience, and sincere faith,"},{"v":6,"t":"from which things some, having missed the mark, have turned away to vain talking,"},{"v":7,"t":"desiring to be teachers of the law, though they understand neither what they say nor about what they strongly affirm."},{"v":8,"t":"But we know that the law is good if a person uses it lawfully,"},{"v":9,"t":"as knowing this, that law is not made for a righteous person, but for the lawless and insubordinate, for the ungodly and sinners, for the unholy and profane, for murderers of fathers and murderers of mothers, for manslayers,"},{"v":10,"t":"for the sexually immoral, for homosexuals, for slave-traders, for liars, for perjurers, and for any other thing contrary to the sound doctrine,"},{"v":11,"t":"according to the Good News of the glory of the blessed God, which was committed to my trust."},{"v":12,"t":"I thank him who enabled me, Christ Jesus our Lord, because he counted me faithful, appointing me to service,"},{"v":13,"t":"although I used to be a blasphemer, a persecutor, and insolent. However, I obtained mercy because I did it ignorantly in unbelief."},{"v":14,"t":"The grace of our Lord abounded exceedingly with faith and love which is in Christ Jesus."},{"v":15,"t":"The saying is faithful and worthy of all acceptance, that Christ Jesus came into the world to save sinners, of whom I am chief."},{"v":16,"t":"However, for this cause I obtained mercy, that in me first, Jesus Christ might display all his patience for an example of those who were going to believe in him for eternal life."},{"v":17,"t":"Now to the King eternal, immortal, invisible, to God who alone is wise, be honor and glory forever and ever. Amen."},{"v":18,"t":"I commit this instruction to you, my child Timothy, according to the prophecies which were given to you before, that by them you may wage the good warfare,"},{"v":19,"t":"holding faith and a good conscience, which some having thrust away made a shipwreck concerning the faith,"},{"v":20,"t":"of whom are Hymenaeus and Alexander, whom I delivered to Satan that they might be taught not to blaspheme."}],"hr":[{"v":1,"t":"Pavao, apostol Krista Isusa po nalogu Boga, Spasitelja našega, i Krista Isusa, nade naše,"},{"v":2,"t":"Timoteju, pravomu sinu u vjeri: milost, milosrđe i mir od Boga Oca i Krista Isusa, Gospodina našega!"},{"v":3,"t":"Kao što sam te zamolio kad sam odlazio u Makedoniju, ostani u Efezu da zapovijediš nekima neka ne naučavaju drugih nauka"},{"v":4,"t":"i neka se ne zanose beskrajnim bajkama i rodoslovljima, koja više pogoduju rasprama negoli rasporedbi Božjoj po vjeri."},{"v":5,"t":"Svrha je te zapovijedi ljubav iz čista srca, dobre savjesti i vjere neprijetvorne."},{"v":6,"t":"To su neki promašili i zastranili u praznorječje;"},{"v":7,"t":"htjeli bi biti učitelji Zakona, a ne razumiju ni što govore ni što tvrde."},{"v":8,"t":"A mi znamo da je Zakon dobar ako se tko njime služi zakonito,"},{"v":9,"t":"svjestan toga da je Zakon tu ne za pravednika nego za bezakonike i nepokornike, nepobožnike i grešnike, bezbožnike i svetogrdnike, ocoubojice i materoubojice, koljače,"},{"v":10,"t":"bludnike, muškoložnike, trgovce ljudima, varalice, krivokletnike, i ima li još što protivno zdravom nauku -"},{"v":11,"t":"po evanđelju Slave blaženoga Boga koje je meni povjereno."},{"v":12,"t":"Zahvalan sam Onome koji mi dade snagu - Kristu Isusu, Gospodinu našemu - jer me smatrao vrijednim povjerenja, kad u službu postavi mene"},{"v":13,"t":"koji prije bijah hulitelj, progonitelj i nasilnik. Ali pomilovan sam jer sam to u neznanju učinio, još u nevjeri."},{"v":14,"t":"I milost Gospodina našega preobilovala je zajedno s vjerom i ljubavlju, u Kristu Isusu."},{"v":15,"t":"Vjerodostojna je riječ i vrijedna da se posve prihvati: Isus Krist dođe na svijet spasiti grešnike, od kojih sam prvi ja."},{"v":16,"t":"A pomilovan sam zato da na meni prvome Isus Krist pokaže svu strpljivost i pruži primjer svima koji će povjerovati u njega za život vječni."},{"v":17,"t":"A Kralju vjekova, besmrtnome, nevidljivome, jedinome Bogu čast i slava u vijeke vjekova. Amen."},{"v":18,"t":"Taj ti zadatak predajem, sine Timoteju, u skladu s proroštvima nekoć nad tobom izrečenima: na njih oslonjen, bij boj plemeniti"},{"v":19,"t":"imajući vjeru i dobru savjest, koju su neki odbacili i doživjeli brodolom vjere."},{"v":20,"t":"Među njima je Himenej i Aleksandar, koje sam predao Sotoni da nauče ne huliti."}]},"2":{"fa":[{"v":1,"t":"پس از همه‌چیز اول، سفارش می‌کنم که صلوات و دعاها و مناجات و شکرها رابرای جمیع مردم به‌جا آورند؛"},{"v":2,"t":"بجهت پادشاهان و جمیع صاحبان منصب تا به آرامی و استراحت و با کمال دینداری و وقار، عمر خود را بسر بریم."},{"v":3,"t":"زیرا که این نیکو و پسندیده است، در حضورنجات‌دهنده ما خدا"},{"v":4,"t":"که می‌خواهد جمیع مردم نجات یابند و به معرفت راستی گرایند."},{"v":5,"t":"زیراخدا واحد است و در میان خدا و انسان یک متوسطی است یعنی انسانی که مسیح عیسی باشد،"},{"v":6,"t":"که خود را در راه همه فدا داد، شهادتی درزمان معین."},{"v":7,"t":"و برای این، من واعظ و رسول ومعلم امتها در ایمان و راستی مقرر شدم. در مسیح راست می‌گویم و دروغ نی."},{"v":8,"t":"پس آرزوی این دارم که مردان، دست های مقدس را بدون غیظ و جدال برافراخته، در هر جادعا کنند."},{"v":9,"t":"و همچنین زنان خویشتن را بیارایند به لباس مزین به حیا و پرهیز نه به زلفها و طلا ومروارید و رخت گرانبها؛"},{"v":10,"t":"بلکه چنانکه زنانی رامی شاید که دعوای دینداری می‌کنند به اعمال صالحه."},{"v":11,"t":"زن با سکوت، به‌کمال اطاعت تعلیم گیرد."},{"v":12,"t":"و زن را اجازت نمی دهم که تعلیم دهد یابر شوهر مسلط شود بلکه در سکوت بماند."},{"v":13,"t":"زیرا که آدم اول ساخته شد و بعد حوا."},{"v":14,"t":"وآدم فریب نخورد بلکه زن فریب خورده، درتقصیر گرفتار شد."},{"v":15,"t":"اما به زاییدن رستگارخواهد شد، اگر در ایمان و محبت و قدوسیت وتقوا ثابت بمانند."}],"en":[{"v":1,"t":"I exhort therefore, first of all, that petitions, prayers, intercessions, and givings of thanks be made for all men,"},{"v":2,"t":"for kings and all who are in high places, that we may lead a tranquil and quiet life in all godliness and reverence."},{"v":3,"t":"For this is good and acceptable in the sight of God our Savior,"},{"v":4,"t":"who desires all people to be saved and come to full knowledge of the truth."},{"v":5,"t":"For there is one God and one mediator between God and men, the man Christ Jesus,"},{"v":6,"t":"who gave himself as a ransom for all, the testimony at the proper time,"},{"v":7,"t":"to which I was appointed a preacher and an apostle—I am telling the truth in Christ, not lying—a teacher of the Gentiles in faith and truth."},{"v":8,"t":"I desire therefore that the men in every place pray, lifting up holy hands without anger and doubting."},{"v":9,"t":"In the same way, that women also adorn themselves in decent clothing, with modesty and propriety, not with braided hair, gold, pearls, or expensive clothing,"},{"v":10,"t":"but with good works, which is appropriate for women professing godliness."},{"v":11,"t":"Let a woman learn in quietness with full submission."},{"v":12,"t":"But I don’t permit a woman to teach, nor to exercise authority over a man, but to be in quietness."},{"v":13,"t":"For Adam was formed first, then Eve."},{"v":14,"t":"Adam wasn’t deceived, but the woman, being deceived, has fallen into disobedience;"},{"v":15,"t":"but she will be saved through her childbearing, if they continue in faith, love, and holiness with sobriety."}],"hr":[{"v":1,"t":"Dakle, preporučujem prije svega da se obavljaju prošnje, molitve, molbenice i zahvalnice za sve ljude,"},{"v":2,"t":"za kraljeve i sve koji su na vlasti, da provodimo miran i spokojan život u svoj bogoljubnosti i ozbiljnosti."},{"v":3,"t":"To je dobro i ugodno pred Spasiteljem našim Bogom,"},{"v":4,"t":"koji hoće da se svi ljudi spase i dođu do spoznanja istine."},{"v":5,"t":"Jer jedan je Bog, jedan je i posrednik između Boga i ljudi, čovjek - Krist Isus,"},{"v":6,"t":"koji sebe samoga dade kao otkup za sve. To je u svoje vrijeme dano svjedočanstvo,"},{"v":7,"t":"za koje sam ja postavljen propovjednikom i apostolom - istinu govorim, ne lažem - učiteljem naroda u vjeri i istini."},{"v":8,"t":"Hoću dakle da muškarci mole na svakome mjestu, podižući čiste ruke bez srdžbe i raspre;"},{"v":9,"t":"isto tako žene - u doličnu držanju: neka se rese stidljivošću i razborom, ne pletenicama i zlatom ili biserjem ili skupocjenim odijelom,"},{"v":10,"t":"nego - dobrim djelima, kako dolikuje ženama koje ispovijedaju bogoljubnost."},{"v":11,"t":"Žena neka u miru prima pouku sa svom podložnošću."},{"v":12,"t":"Poučavati pak ženi ne dopuštam, ni vladati nad mužem, nego - neka bude na miru."},{"v":13,"t":"Jer prvi je oblikovan Adam, onda Eva;"},{"v":14,"t":"i Adam nije zaveden, a žena je, zavedena, učinila prekršaj."},{"v":15,"t":"A spasit će se rađanjem djece ako ustraje u vjeri, ljubavi i posvećivanju, s razborom."}]},"3":{"fa":[{"v":1,"t":"این سخن امین است که اگر کسی منصب اسقفی را بخواهد، کار نیکو می‌طلبد."},{"v":2,"t":"پس اسقف باید بی‌ملامت و صاحب یک زن و هشیارو خردمند و صاحب نظام و مهمان‌نواز و راغب به تعلیم باشد؛"},{"v":3,"t":"نه میگسار یا زننده یا طماع سودقبیح بلکه حلیم و نه جنگجو و نه زرپرست."},{"v":4,"t":"مدبر اهل خانه خود، به نیکویی و فرزندان خویش را در کمال وقار مطیع گرداند،"},{"v":5,"t":"زیراهرگاه کسی نداند که اهل خانه خود را تدبیر کند، چگونه کلیسای خدا را نگاهبانی می‌نماید؟"},{"v":6,"t":"و نه جدیدالایمان که مبادا غرور کرده، به حکم ابلیس بیفتد."},{"v":7,"t":"اما لازم است که نزد آنانی که خارجند هم نیک نام باشد که مبادا در رسوایی و دام ابلیس گرفتار شود."},{"v":8,"t":"همچنین شماسان باوقار باشند، نه دو زبان ونه راغب به شراب زیاده و نه طماع سود قبیح؛"},{"v":9,"t":"دارندگان سر ایمان در ضمیر پاک."},{"v":10,"t":"اما بایداول ایشان آزموده شوند و چون بی‌عیب یافت شدند، کار شماسی را بکنند."},{"v":11,"t":"و به همینطورزنان نیز باید باوقار باشند و نه غیبت‌گو بلکه هشیارو در هر امری امین."},{"v":12,"t":"و شماسان صاحب یک زن باشند و فرزندان و اهل خانه خویش را نیکو تدبیرنمایند،"},{"v":13,"t":"زیرا آنانی که کار شماسی را نیکو کرده باشند، درجه خوب برای خویشتن تحصیل می‌کنند و جلادت کامل در ایمانی که به مسیح عیسی است."},{"v":14,"t":"این به تو می‌نویسم به امید آنکه به زودی نزد تو آیم."},{"v":15,"t":"لیکن اگر تاخیر اندازم، تا بدانی که چگونه باید در خانه خدا رفتار کنی که کلیسای خدای حی و ستون و بنیاد راستی است."},{"v":16,"t":"وبالاجماع سر دینداری عظیم است که خدا درجسم ظاهر شد و در روح، تصدیق کرده شد و به فرشتگان، مشهود گردید و به امتها موعظه کرده ودر دنیا ایمان آورده و به جلال بالا برده شد."}],"en":[{"v":1,"t":"This is a faithful saying: someone who seeks to be an overseer desires a good work."},{"v":2,"t":"The overseer therefore must be without reproach, the husband of one wife, temperate, sensible, modest, hospitable, good at teaching;"},{"v":3,"t":"not a drinker, not violent, not greedy for money, but gentle, not quarrelsome, not covetous;"},{"v":4,"t":"one who rules his own house well, having children in subjection with all reverence;"},{"v":5,"t":"(for how could someone who doesn’t know how to rule his own house take care of God’s assembly?)"},{"v":6,"t":"not a new convert, lest being puffed up he fall into the same condemnation as the devil."},{"v":7,"t":"Moreover he must have good testimony from those who are outside, to avoid falling into reproach and the snare of the devil."},{"v":8,"t":"Servants, in the same way, must be reverent, not double-tongued, not addicted to much wine, not greedy for money,"},{"v":9,"t":"holding the mystery of the faith in a pure conscience."},{"v":10,"t":"Let them also first be tested; then let them serve if they are blameless."},{"v":11,"t":"Their wives in the same way must be reverent, not slanderers, temperate, and faithful in all things."},{"v":12,"t":"Let servants be husbands of one wife, ruling their children and their own houses well."},{"v":13,"t":"For those who have served well gain for themselves a good standing and great boldness in the faith which is in Christ Jesus."},{"v":14,"t":"These things I write to you, hoping to come to you shortly,"},{"v":15,"t":"but if I wait long, that you may know how men ought to behave themselves in God’s house, which is the assembly of the living God, the pillar and ground of the truth."},{"v":16,"t":"Without controversy, the mystery of godliness is great: God was revealed in the flesh, justified in the spirit, seen by angels, preached among the nations, believed on in the world, and received up in glory."}],"hr":[{"v":1,"t":"Vjerodostojna je riječ: teži li tko za nadgledništvom, časnu službu želi."},{"v":2,"t":"Treba stoga da nadglednik bude besprijekoran, jedne žene muž, trijezan, razuman, sređen, gostoljubiv, sposoban poučavati,"},{"v":3,"t":"ne vinu sklon, ne nasilan nego popustljiv, ne ratoboran, ne srebroljubac;"},{"v":4,"t":"da svojom kućom dobro upravlja i sinove drži u pokornosti sa svom ozbiljnošću -"},{"v":5,"t":"a ne zna li netko svojom kućom upravljati, kako će se brinuti za Crkvu Božju? -"},{"v":6,"t":"ne novoobraćenik da se ne bi uzoholio i pao pod osudu đavlovu."},{"v":7,"t":"A treba da ima i lijepo svjedočanstvo od onih vani, da ne bi u rug upao i zamku đavlovu."},{"v":8,"t":"Ðakoni isto tako treba da budu ozbiljni, ne dvolični, ne odani mnogom vinu ni prljavu dobitku -"},{"v":9,"t":"imajući otajstvo vjere u čistoj savjesti."},{"v":10,"t":"I neka se najprije iskušavaju, pa onda, budu li besprigovorni, neka obavljaju službu."},{"v":11,"t":"Žene isto tako neka budu ozbiljne, ne klevetnice nego trijezne, vjerne u svemu."},{"v":12,"t":"đakoni neka budu jedne žene muževi, neka dobro upravljaju djecom i svojim kućama."},{"v":13,"t":"Jer oni koji dobro obavljaju službu, stječu častan položaj i veliku smjelost u vjeri, vjeri u Isusu Kristu."},{"v":14,"t":"Ovo ti pišem u nadi da ću ubrzo doći k tebi,"},{"v":15,"t":"a okasnim li, da znaš kako se treba vladati u kući Božjoj, koja je Crkva Boga živoga, stup i uporište istine."},{"v":16,"t":"Da, po sveopćem uvjerenju, veliko je Otajstvo pobožnosti: On, očitovan u tijelu, opravdan u Duhu, viđen od anđela, propovijedan među narodima, vjerovan u svijetu, uznesen u slavu."}]},"4":{"fa":[{"v":1,"t":"و لیکن روح صریح می‌گوید که در زمان آخر بعضی از ایمان برگشته، به ارواح مضل و تعالیم شیاطین اصغا خواهند نمود،"},{"v":2,"t":"به ریاکاری دروغگویان که ضمایر خود را داغ کرده‌اند؛"},{"v":3,"t":"که از مزاوجت منع می‌کنند و حکم می‌نمایند به احتراز از خوراک هایی که خدا آفریدبرای مومنین و عارفین حق تا آنها را به شکرگزاری بخورند."},{"v":4,"t":"زیرا که هر مخلوق خدا نیکو است وهیچ‌چیز را رد نباید کرد، اگر به شکرگزاری پذیرند،"},{"v":5,"t":"زیرا که از کلام خدا و دعا تقدیس می‌شود."},{"v":6,"t":"اگر این امور را به برادران بسپاری، خادم نیکوی مسیح عیسی خواهی بود، تربیت یافته درکلام ایمان و تعلیم خوب که پیروی آن راکرده‌ای."},{"v":7,"t":"لیکن از افسانه های حرام عجوزهااحتراز نما و در دینداری ریاضت بکش."},{"v":8,"t":"که ریاضت بدنی اندک فایده‌ای دارد، لیکن دینداری برای هر چیز مفید است که وعده زندگی حال وآینده را دارد."},{"v":9,"t":"این سخن امین است و لایق قبول تام،"},{"v":10,"t":"زیراکه برای این زحمت و بی‌احترامی می‌کشیم، زیراامید داریم به خدای زنده که جمیع مردمان علی الخصوص مومنین را نجات‌دهنده است."},{"v":11,"t":"این امور را حکم و تعلیم فرما."},{"v":12,"t":"هیچ‌کس جوانی تو را حقیر نشمارد، بلکه مومنین را درکلام و سیرت و محبت و ایمان و عصمت، نمونه باش."},{"v":13,"t":"تا مادامی که نه آیم، خود را به قرائت ونصیحت و تعلیم بسپار."},{"v":14,"t":"زنهار از آن کرامتی که در تو است که بوسیله نبوت با نهادن دستهای کشیشان به تو داده شد، بی‌اعتنایی منما."},{"v":15,"t":"در این امور تامل نما و در اینها راسخ باش تا ترقی تو برهمه ظاهر شود."},{"v":16,"t":"خویشتن را و تعلیم را احتیاطکن و در این امور قائم باش که هرگاه چنین کنی، خویشتن را و شنوندگان خویش را نیز نجات خواهی داد."}],"en":[{"v":1,"t":"But the Spirit says expressly that in later times some will fall away from the faith, paying attention to seducing spirits and doctrines of demons,"},{"v":2,"t":"through the hypocrisy of men who speak lies, branded in their own conscience as with a hot iron,"},{"v":3,"t":"forbidding marriage and commanding to abstain from foods which God created to be received with thanksgiving by those who believe and know the truth."},{"v":4,"t":"For every creature of God is good, and nothing is to be rejected if it is received with thanksgiving."},{"v":5,"t":"For it is sanctified through the word of God and prayer."},{"v":6,"t":"If you instruct the brothers of these things, you will be a good servant of Christ Jesus, nourished in the words of the faith and of the good doctrine which you have followed."},{"v":7,"t":"But refuse profane and old wives’ fables. Exercise yourself toward godliness."},{"v":8,"t":"For bodily exercise has some value, but godliness has value in all things, having the promise of the life which is now and of that which is to come."},{"v":9,"t":"This saying is faithful and worthy of all acceptance."},{"v":10,"t":"For to this end we both labor and suffer reproach, because we have set our trust in the living God, who is the Savior of all men, especially of those who believe."},{"v":11,"t":"Command and teach these things."},{"v":12,"t":"Let no man despise your youth; but be an example to those who believe, in word, in your way of life, in love, in spirit, in faith, and in purity."},{"v":13,"t":"Until I come, pay attention to reading, to exhortation, and to teaching."},{"v":14,"t":"Don’t neglect the gift that is in you, which was given to you by prophecy with the laying on of the hands of the elders."},{"v":15,"t":"Be diligent in these things. Give yourself wholly to them, that your progress may be revealed to all."},{"v":16,"t":"Pay attention to yourself and to your teaching. Continue in these things, for in doing this you will save both yourself and those who hear you."}],"hr":[{"v":1,"t":"Duh izričito govori da će u posljednja vremena neki otpasti od vjere i prikloniti se prijevarnim duhovima i zloduhovskim naucima."},{"v":2,"t":"A sve to pod utjecajem himbe lažljivaca otupjele savjesti"},{"v":3,"t":"koji zabranjuju ženiti se i nameću uzdržavati se od jela što ih je Bog stvorio da ih sa zahvalnošću uzimaju oni koji vjeruju i znaju istinu."},{"v":4,"t":"Doista, svako je Božje stvorenje dobro i ne valja odbaciti ništa što se uzima sa zahvalnošću"},{"v":5,"t":"jer se posvećuje riječju Božjom i molitvom."},{"v":6,"t":"To izlaži braći i bit ćeš dobar poslužitelj Krista Isusa, hranjen riječima vjere i dobroga nauka za kojim postojano ideš."},{"v":7,"t":"Svjetovne pak i bablje priče odbijaj! Vježbaj se u pobožnosti!"},{"v":8,"t":"Uistinu, tjelesno vježbanje malo čemu koristi, a pobožnost je svemu korisna jer joj je obećan život - sadašnji i budući."},{"v":9,"t":"Vjerodostojna je to riječ i vrijedna da se posve prihvati."},{"v":10,"t":"Ta za to se trudimo i borimo jer se pouzdajemo u Boga živoga koji je Spasitelj svih ljudi, ponajpače vjernika."},{"v":11,"t":"Zapovijedaj to i naučavaj!"},{"v":12,"t":"Nitko neka ne prezire tvoje mladosti, nego budi uzor vjernicima u riječi, u vladanju, u ljubavi, u vjeri, u čistoći."},{"v":13,"t":"Dok ne dođem, posveti se čitanju, poticanju, poučavanju."},{"v":14,"t":"Ne zanemari milosnog dara koji je u tebi, koji ti je dan po proroštvu zajedno s polaganjem ruku starješinstva."},{"v":15,"t":"Oko toga nastoj, sav u tom budi da tvoj napredak bude svima očit."},{"v":16,"t":"Pripazi na samog sebe i na poučavanje! Ustraj u tome! Jer to vršeći, spasit ćeš i sebe i one koji te slušaju."}]},"5":{"fa":[{"v":1,"t":"مرد پیر را توبیخ منما بلکه چون پدر او رانصیحت کن، و جوانان را چون برادران؛"},{"v":2,"t":"زنان پیر را چون مادران؛ و زنان جوان را مثل خواهران با کمال عفت؛"},{"v":3,"t":"بیوه‌زنان را اگرفی الحقیقت بیوه باشند، محترم دار."},{"v":4,"t":"اما اگربیوه‌زنی فرزندان یا نواده‌ها دارد، آموخته بشوندکه خانه خود را با دینداری نگاه دارند و حقوق اجداد خود را ادا کنند که این در حضور خدا نیکوو پسندیده است."},{"v":5,"t":"اما زنی که فی الحقیقت بیوه وبی کس است، به خدا امیدوار است و در صلوات ودعاها شبانه‌روز مشغول می‌باشد."},{"v":6,"t":"لیکن زن عیاش در حال حیات مرده است."},{"v":7,"t":"و به این معانی امر فرما تا بی‌ملامت باشند."},{"v":8,"t":"ولی اگر کسی برای خویشان و علی الخصوص اهل خانه خود تدبیرنکند، منکر ایمان و پست‌تر از بی‌ایمان است."},{"v":9,"t":"بیوه‌زنی که کمتر از شصت ساله نباشد و یک شوهر کرده باشد، باید نام او ثبت گردد،"},{"v":10,"t":"که دراعمال صالح نیک نام باشد، اگر فرزندان را پرورده و غربا را مهمانی نموده و پایهای مقدسین راشسته و زحمت کشان را اعانتی نموده و هر کارنیکو را پیروی کرده باشد."},{"v":11,"t":"اما بیوه های جوانتراز این را قبول مکن، زیرا که چون از مسیح سرکش شوند، خواهش نکاح دارند"},{"v":12,"t":"و ملزم می‌شوند ازاینکه ایمان نخست را برطرف کرده‌اند؛"},{"v":13,"t":"وعلاوه بر این خانه به خانه گردش کرده، آموخته می‌شوند که بی‌کار باشند؛ و نه فقط بی‌کار بلکه بیهوده گو و فضول هم که حرفهای ناشایسته می‌زنند."},{"v":14,"t":"پس رای من این است که زنان جوان نکاح شوند و اولاد بزایند و کدبانو شوند و خصم را مجال مذمت ندهند؛"},{"v":15,"t":"زیرا که بعضی برگشتندبه عقب شیطان."},{"v":16,"t":"اگر مرد یا زن مومن، بیوه هادارد ایشان را بپرورد و بار بر کلیسا ننهد تا آنانی راکه فی الحقیقت بیوه باشند، پرورش نماید."},{"v":17,"t":"کشیشانی که نیکو پیشوایی کرده‌اند، مستحق حرمت مضاعف می‌باشند، علی الخصوص آنانی که در کلام و تعلیم محنت می‌کشند."},{"v":18,"t":"زیرا کتاب می‌گوید: «گاو را وقتی که خرمن را خرد می‌کند، دهن مبند» و «مزدورمستحق اجرت خود است»."},{"v":19,"t":"ادعایی بر یکی ازکشیشان جز به زبان دو یا سه شاهد مپذیر."},{"v":20,"t":"آنانی که گناه کنند، پیش همه توبیخ فرما تا دیگران بترسند."},{"v":21,"t":"در حضور خدا و مسیح عیسی و فرشتگان برگزیده تو را قسم می‌دهم که این امور را بدون غرض نگاه داری و هیچ کاری از روی طرفداری مکن."},{"v":22,"t":"و دستها به زودی بر هیچ‌کس مگذار و درگناهان دیگران شریک مشو بلکه خود را طاهرنگاه دار."},{"v":23,"t":"دیگر آشامنده آب فقط مباش، بلکه بجهت شکمت و ضعفهای بسیار خود شرابی کم میل فرما."},{"v":24,"t":"گناهان بعضی آشکار است و پیش روی ایشان به داوری می‌خرامد، اما بعضی را تعاقب می‌کند."},{"v":25,"t":"و همچنین اعمال نیکو واضح است وآنهایی که دیگرگون باشد، نتوان مخفی داشت."}],"en":[{"v":1,"t":"Don’t rebuke an older man, but exhort him as a father; the younger men as brothers;"},{"v":2,"t":"the elder women as mothers; the younger as sisters, in all purity."},{"v":3,"t":"Honor widows who are widows indeed."},{"v":4,"t":"But if any widow has children or grandchildren, let them learn first to show piety toward their own family and to repay their parents, for this is acceptable in the sight of God."},{"v":5,"t":"Now she who is a widow indeed and desolate, has her hope set on God and continues in petitions and prayers night and day."},{"v":6,"t":"But she who gives herself to pleasure is dead while she lives."},{"v":7,"t":"Also command these things, that they may be without reproach."},{"v":8,"t":"But if anyone doesn’t provide for his own, and especially his own household, he has denied the faith and is worse than an unbeliever."},{"v":9,"t":"Let no one be enrolled as a widow under sixty years old, having been the wife of one man,"},{"v":10,"t":"being approved by good works, if she has brought up children, if she has been hospitable to strangers, if she has washed the saints’ feet, if she has relieved the afflicted, and if she has diligently followed every good work."},{"v":11,"t":"But refuse younger widows, for when they have grown wanton against Christ, they desire to marry,"},{"v":12,"t":"having condemnation, because they have rejected their first pledge."},{"v":13,"t":"Besides, they also learn to be idle, going about from house to house. Not only idle, but also gossips and busybodies, saying things which they ought not."},{"v":14,"t":"I desire therefore that the younger widows marry, bear children, rule the household, and give no occasion to the adversary for insulting."},{"v":15,"t":"For already some have turned away after Satan."},{"v":16,"t":"If any man or woman who believes has widows, let them relieve them, and don’t let the assembly be burdened, that it might relieve those who are widows indeed."},{"v":17,"t":"Let the elders who rule well be counted worthy of double honor, especially those who labor in the word and in teaching."},{"v":18,"t":"For the Scripture says, “You shall not muzzle the ox when it treads out the grain.” And, “The laborer is worthy of his wages.”"},{"v":19,"t":"Don’t receive an accusation against an elder except at the word of two or three witnesses."},{"v":20,"t":"Those who sin, reprove in the sight of all, that the rest also may be in fear."},{"v":21,"t":"I command you in the sight of God, and the Lord Jesus Christ, and the chosen angels, that you observe these things without prejudice, doing nothing by partiality."},{"v":22,"t":"Lay hands hastily on no one. Don’t be a participant in other people’s sins. Keep yourself pure."},{"v":23,"t":"Be no longer a drinker of water only, but use a little wine for your stomach’s sake and your frequent infirmities."},{"v":24,"t":"Some men’s sins are evident, preceding them to judgment, and some also follow later."},{"v":25,"t":"In the same way also there are good works that are obvious, and those that are otherwise can’t be hidden."}],"hr":[{"v":1,"t":"Na starca se ne otresaj, nego ga nagovaraj kao oca, mladiće kao braću,"},{"v":2,"t":"starice kao majke, djevojke kao sestre - u svoj čistoći."},{"v":3,"t":"Udovice poštuj - one koje su zaista udovice."},{"v":4,"t":"Ako li ipak koja udovica ima djecu ili unuke, neka najprije oni znaju očitovati svoju pobožnost prema vlastitom domu i uzdarjem uzvraćati roditeljima jer to je ugodno Bogu."},{"v":5,"t":"A ona koja je zaista udovica, posve sama, pouzdaje se u Boga, odana prošnjama i molitvama noć i dan;"},{"v":6,"t":"ona, naprotiv, koja provodi lagodan život, živa je već umrla."},{"v":7,"t":"I to naglašuj da budu besprijekorne."},{"v":8,"t":"Ako li se tkogod za svoje, navlastito za ukućane, ne stara, zanijekao je vjeru i gori je od nevjernika."},{"v":9,"t":"U popis neka se unosi udovica ne mlađa od šezdeset godina, jednog muža žena,"},{"v":10,"t":"koja ima svjedočanstvo dobrih djela: da je djecu odgojila, da je bila gostoljubiva, da je svetima noge prala, da je nevoljnima pomagala, da se svakom dobru djelu posvećivala."},{"v":11,"t":"Mlađe pak udovice odbijaj jer kad ih požuda odvrati od Krista, hoće se udati,"},{"v":12,"t":"pa zasluže osudu što su pogazile prvotnu vjernost."},{"v":13,"t":"A uz to se, obilazeći po kućama, nauče biti besposlene, i ne samo besposlene, nego i brbljave i nametljive, govoreći što ne bi smjele."},{"v":14,"t":"Hoću dakle da se mlađe udaju, djecu rađaju, da budu kućevne te ne daju protivniku nikakva povoda za pogrđivanje."},{"v":15,"t":"Jer već su neke zastranile za Sotonom."},{"v":16,"t":"Ako koja vjernica ima udovica, neka im pomaže, a neka se ne opterećuje Crkva, da uzmogne pomoći onima koje su zaista udovice."},{"v":17,"t":"Starješine koji su dobri predstojnici dostojni su dvostruke časti, ponajpače oni koji se trude oko Riječi i poučavanja."},{"v":18,"t":"Pismo doista veli: Volu koji vrši ne zavezuj usta! I: Vrijedan je radnik plaće svoje."},{"v":19,"t":"Protiv starješine ne primaj tužbe, osim na osnovi dvaju ili triju svjedoka."},{"v":20,"t":"One koji griješe, pred svima ukori da i drugi imaju straha!"},{"v":21,"t":"Zaklinjem te pred Bogom i Kristom Isusom i izabranim anđelima da se toga držiš bez predrasude i ništa ne činiš po naklonosti."},{"v":22,"t":"Ruku prebrzo ni na koga ne polaži i ne budi dionikom tuđih grijeha! Sebe čistim čuvaj!"},{"v":23,"t":"Ne pij više samo vode, nego uzimaj malo vina poradi želuca i čestih svojih slabosti."},{"v":24,"t":"Grijesi nekih ljudi očiti su i prije suda, nekih pak samo nakon njega."},{"v":25,"t":"Tako su i dobra djela očita, a bila i drukčija, ne mogu se sakriti."}]},"6":{"fa":[{"v":1,"t":"آنانی که غلامان زیر یوغ می‌باشند، آقایان خویش را لایق کمال احترام بدانند که مبادانام و تعلیم خدا بد گفته شود."},{"v":2,"t":"اما کسانی که آقایان مومن دارند، ایشان را تحقیر ننمایند، ازآنجا که برادرانند بلکه بیشتر خدمت کنند از آنروکه آنانی که در این احسان مشارکند، مومن ومحبوبند."},{"v":3,"t":"و اگرکسی بطور دیگر تعلیم دهد و کلام صحیح خداوند ما عیسی مسیح و آن تعلیمی را که به طریق دینداری است قبول ننماید،"},{"v":4,"t":"از غرورمست شده، هیچ نمی داند بلکه در مباحثات ومجادلات دیوانه گشته است که از آنها پدیدمی آید حسد و نزاع و کفر و ظنون شر"},{"v":5,"t":"و منازعات مردم فاسدالعقل و مرتد از حق که می‌پندارند دینداری سود است. از چنین اشخاص اعراض نما."},{"v":6,"t":"لیکن دینداری با قناعت سود عظیمی است."},{"v":7,"t":"زیرا که در این دنیا هیچ نیاوردیم و واضح است که از آن هیچ نمی توانیم برد."},{"v":8,"t":"پس اگر خوراک وپوشاک داریم، به آنها قانع خواهیم بود."},{"v":9,"t":"اماآنانی که می‌خواهند دولتمند شوند، گرفتارمی شوند در تجربه و دام و انواع شهوات بی‌فهم ومضر که مردم را به تباهی و هلاکت غرق می‌سازند."},{"v":10,"t":"زیرا که طمع ریشه همه بدیهااست که بعضی چون در‌پی آن می‌کوشیدند، ازایمان گمراه گشته، خود را به اقسام دردهاسفتند."},{"v":11,"t":"ولی تو‌ای مرد خدا، از اینها بگریز وعدالت و دینداری و ایمان و محبت و صبر وتواضع را پیروی نما."},{"v":12,"t":"و جنگ نیکوی ایمان رابکن و بدست آور آن حیات جاودانی را که برای آن دعوت شدی و اعتراف نیکو کردی در حضورگواهان بسیار."},{"v":13,"t":"تو را وصیت می‌کنم به حضور آن خدایی که همه را زندگی می‌بخشد و مسیح عیسی که در‌پیش پنطیوس پیلاطس اعتراف نیکونمود،"},{"v":14,"t":"که تو وصیت را بی‌داغ و ملامت حفظکن تا به ظهور خداوند ما عیسی مسیح."},{"v":15,"t":"که آن را آن متبارک و قادر وحید و ملک الملوک ورب‌الارباب در زمان معین به ظهور خواهد آورد."},{"v":16,"t":"که تنها لایموت و ساکن در نوری است که نزدیک آن نتوان شد و احدی از انسان او را ندیده و نمی تواند دید. او را تا ابدالاباد اکرام و قدرت باد. آمین."},{"v":17,"t":"دولتمندان این جهان را امر فرما که بلندپروازی نکنند و به دولت ناپایدار امید ندارند، بلکه به خدای زنده که همه‌چیز را دولتمندانه برای تمتع به ما عطا می‌کند؛"},{"v":18,"t":"که نیکوکار بوده، در اعمال صالحه دولتمند و سخی و گشاده‌دست باشند؛"},{"v":19,"t":"و برای خود اساس نیکو بجهت عالم آینده نهند تا حیات جاودانی را بدست آرند."},{"v":20,"t":"‌ای تیموتاوس تو آن امانت را محفوظ دار واز بیهوده‌گویی های حرام و از مباحثات معرفت دروغ اعراض نما،"},{"v":21,"t":"که بعضی چون ادعای آن کردند از ایمان منحرف گشتند. فیض با تو باد. آمین."}],"en":[{"v":1,"t":"Let as many as are bondservants under the yoke count their own masters worthy of all honor, that the name of God and the doctrine not be blasphemed."},{"v":2,"t":"Those who have believing masters, let them not despise them because they are brothers, but rather let them serve them, because those who partake of the benefit are believing and beloved. Teach and exhort these things."},{"v":3,"t":"If anyone teaches a different doctrine and doesn’t consent to sound words, the words of our Lord Jesus Christ, and to the doctrine which is according to godliness,"},{"v":4,"t":"he is conceited, knowing nothing, but obsessed with arguments, disputes, and word battles, from which come envy, strife, insulting, evil suspicions,"},{"v":5,"t":"constant friction of people of corrupt minds and destitute of the truth, who suppose that godliness is a means of gain. Withdraw yourself from such."},{"v":6,"t":"But godliness with contentment is great gain."},{"v":7,"t":"For we brought nothing into the world, and we certainly can’t carry anything out."},{"v":8,"t":"But having food and clothing, we will be content with that."},{"v":9,"t":"But those who are determined to be rich fall into a temptation, a snare, and many foolish and harmful lusts, such as drown men in ruin and destruction."},{"v":10,"t":"For the love of money is a root of all kinds of evil. Some have been led astray from the faith in their greed, and have pierced themselves through with many sorrows."},{"v":11,"t":"But you, man of God, flee these things, and follow after righteousness, godliness, faith, love, perseverance, and gentleness."},{"v":12,"t":"Fight the good fight of faith. Take hold of the eternal life to which you were called, and you confessed the good confession in the sight of many witnesses."},{"v":13,"t":"I command you before God who gives life to all things, and before Christ Jesus who before Pontius Pilate testified the good confession,"},{"v":14,"t":"that you keep the commandment without spot, blameless until the appearing of our Lord Jesus Christ,"},{"v":15,"t":"which at the right time he will show, who is the blessed and only Ruler, the King of kings and Lord of lords."},{"v":16,"t":"He alone has immortality, dwelling in unapproachable light, whom no man has seen nor can see, to whom be honor and eternal power. Amen."},{"v":17,"t":"Charge those who are rich in this present age that they not be arrogant, nor have their hope set on the uncertainty of riches, but on the living God, who richly provides us with everything to enjoy;"},{"v":18,"t":"that they do good, that they be rich in good works, that they be ready to distribute, willing to share;"},{"v":19,"t":"laying up in store for themselves a good foundation against the time to come, that they may lay hold of eternal life."},{"v":20,"t":"Timothy, guard that which is committed to you, turning away from the empty chatter and oppositions of what is falsely called knowledge,"},{"v":21,"t":"which some profess, and thus have wandered from the faith. Grace be with you. Amen."}],"hr":[{"v":1,"t":"Koji su pod jarmom, robovi, neka svoje gospodare smatraju svake časti dostojnima da se ne bi pogrđivalo ime Božje i nauk."},{"v":2,"t":"A oni kojima su gospodari vjernici, neka ih ne cijene manje zato što su braća, nego neka im još više služe jer ti koji primaju njihovo dobročinstvo vjernici su i ljubljena braća. To naučavaj i preporučuj!"},{"v":3,"t":"A tko drukčije naučava i ne prianja uza zdrave riječi, riječi Gospodina našega Isusa Krista, i nauk u skladu s pobožnošću,"},{"v":4,"t":"nadut je, puka neznalica, samo boluje od raspra i rječoborstava, od kojih nastaje zavist, svađa, pogrde, zla sumnjičenja,"},{"v":5,"t":"razračunavanja ljudi pokvarene pameti i lišenih istine, što pobožnost smatraju dobitkom."},{"v":6,"t":"Pa i jest dobitak velik pobožnost, zadovoljna onim što ima!"},{"v":7,"t":"Ta ništa nismo donijeli na svijet te iz njega ništa ni iznijeti ne možemo!"},{"v":8,"t":"Imamo li dakle hranu i odjeću, zadovoljimo se time."},{"v":9,"t":"Jer oni koji se hoće bogatiti, upadaju u napast, zamku i mnoge nerazumne i štetne požude što ljude strovaljuju u zator i propast."},{"v":10,"t":"Zaista, korijen svih zala jest srebroljublje; njemu odani, mnogi odlutaše od vjere i sami sebe isprobadaše mukama mnogima."},{"v":11,"t":"A ti se, Božji čovječe, toga kloni! Teži za pravednošću, pobožnošću, vjerom, ljubavlju, postojanošću, krotkošću!"},{"v":12,"t":"Bij dobar boj vjere, osvoji vječni život na koji si pozvan i radi kojega si dao ono lijepo svjedočanstvo pred mnogim svjedocima!"},{"v":13,"t":"Zapovijedam pred Bogom koji svemu život daje i pred Kristom Isusom koji pred Poncijem Pilatom posvjedoči lijepo svjedočanstvo:"},{"v":14,"t":"čuvaj Zapovijed, neokaljano i besprijekorno, do Pojavka Gospodina našega Isusa Krista."},{"v":15,"t":"Njega će u svoje vrijeme pokazati On, Blaženi i jedini Vladar, Kralj kraljeva i Gospodar gospodara,"},{"v":16,"t":"koji jedini ima besmrtnost, prebiva u svjetlu nedostupnu, koga nitko od ljudi ne vidje niti ga vidjeti može. Njemu čast i vlast vjekovječna! Amen."},{"v":17,"t":"Onima koji su u sadašnjem svijetu bogati zapovijedaj neka ne budu bahati i neka se ne uzdaju u nesigurno bogatstvo, nego u Boga koji nam sve bogato daje na uživanje;"},{"v":18,"t":"neka dobro čine, neka se bogate dobrim djelima, neka budu darežljivi, zajedničari -"},{"v":19,"t":"prikupljajući sebi lijepu glavnicu za budućnost da osvoje onaj pravi život."},{"v":20,"t":"Timoteju, poklad čuvaj kloneći se svjetovnoga praznoglasja i proturječja nekog nazovispoznanja,"},{"v":21,"t":"koje su neki ispovijedali pa od vjere zastranili. Milost s vama"}]}},"2TI":{"1":{"fa":[{"v":1,"t":"پولس به اراده خدا رسول مسیح عیسی، برحسب وعده حیاتی که در مسیح عیسی است،"},{"v":2,"t":"فرزند حبیب خود تیموتاوس را. فیض و رحمت و سلامتی از جانب خدای پدرو خداوند ما عیسی مسیح باد."},{"v":3,"t":"شکر می‌کنم آن خدایی را که از اجداد خودبه ضمیر خالص بندگی او را می‌کنم، چونکه دائم در دعاهای خود تو را شبانه‌روز یاد می‌کنم،"},{"v":4,"t":"و مشتاق ملاقات تو هستم چونکه اشکهای تورا بخاطر می‌دارم تا از خوشی سیر شوم."},{"v":5,"t":"زیرا که یاد می‌دارم ایمان بی‌ریای تو را که نخست درجده ات لوئیس و مادرت افنیکی ساکن می‌بود ومرا یقین است که در تو نیز هست."},{"v":6,"t":"لهذا بیاد تومی آورم که آن عطای خدا را که بوسیله گذاشتن دستهای من بر تو است برافروزی."},{"v":7,"t":"زیرا خداروح جبن را به ما نداده است بلکه روح قوت ومحبت و تادیب را."},{"v":8,"t":"پس از شهادت خداوند ما عار مدار و نه ازمن که اسیر او می‌باشم، بلکه در زحمات انجیل شریک باش برحسب قوت خدا،"},{"v":9,"t":"که ما را نجات داد و به دعوت مقدس خواند نه به حسب اعمال ما بلکه برحسب اراده خود و آن فیضی که قبل ازقدیم الایام در مسیح عیسی به ما عطا شد."},{"v":10,"t":"اماالحال آشکار گردید به ظهور نجات‌دهنده ماعیسی مسیح که موت را نیست ساخت و حیات وبی فسادی را روشن گردانید بوسیله انجیل،"},{"v":11,"t":"که برای آن من واعظ و رسول و معلم امت‌ها مقررشده‌ام."},{"v":12,"t":"و از این جهت این زحمات را می‌کشم بلکه عار ندارم چون می‌دانم به که ایمان آوردم ومرا یقین است که او قادر است که امانت مرا تا به آن روز حفظ کند."},{"v":13,"t":"نمونه‌ای بگیر از سخنان صحیح که از من شنیدی در ایمان و محبتی که در مسیح عیسی است."},{"v":14,"t":"آن امانت نیکو را بوسیله روح‌القدس که در ما ساکن است، حفظ کن."},{"v":15,"t":"از این آگاه هستی که همه آنانی که در آسیا هستند، از من رخ تافته‌اند که از آنجمله فیجلس و هرموجنس می‌باشند."},{"v":16,"t":"خداوند اهل خانه انیسیفورس را ترحم کناد زیرا که او بارها دل مرا تازه کرد و از زنجیر من عار نداشت،"},{"v":17,"t":"بلکه چون به روم رسید، مرا به کوشش بسیار تفحص کرده، پیدا نمود."},{"v":18,"t":"(خداوند بدو عطا کناد که در آن روز در حضورخداوند رحمت یابد. ) و خدمتهایی را که درافسس کرد تو بهتر می‌دانی."}],"en":[{"v":1,"t":"Paul, an apostle of Jesus Christ through the will of God, according to the promise of the life which is in Christ Jesus,"},{"v":2,"t":"to Timothy, my beloved child: Grace, mercy, and peace, from God the Father and Christ Jesus our Lord."},{"v":3,"t":"I thank God, whom I serve as my forefathers did, with a pure conscience. How unceasing is my memory of you in my petitions, night and day"},{"v":4,"t":"longing to see you, remembering your tears, that I may be filled with joy;"},{"v":5,"t":"having been reminded of the sincere faith that is in you, which lived first in your grandmother Lois and your mother Eunice and, I am persuaded, in you also."},{"v":6,"t":"For this cause, I remind you that you should stir up the gift of God which is in you through the laying on of my hands."},{"v":7,"t":"For God didn’t give us a spirit of fear, but of power, love, and self-control."},{"v":8,"t":"Therefore don’t be ashamed of the testimony of our Lord, nor of me his prisoner; but endure hardship for the Good News according to the power of God,"},{"v":9,"t":"who saved us and called us with a holy calling, not according to our works, but according to his own purpose and grace, which was given to us in Christ Jesus before times eternal,"},{"v":10,"t":"but has now been revealed by the appearing of our Savior, Christ Jesus, who abolished death, and brought life and immortality to light through the Good News."},{"v":11,"t":"For this I was appointed as a preacher, an apostle, and a teacher of the Gentiles."},{"v":12,"t":"For this cause I also suffer these things. Yet I am not ashamed, for I know him whom I have believed, and I am persuaded that he is able to guard that which I have committed to him against that day."},{"v":13,"t":"Hold the pattern of sound words which you have heard from me, in faith and love which is in Christ Jesus."},{"v":14,"t":"That good thing which was committed to you, guard through the Holy Spirit who dwells in us."},{"v":15,"t":"This you know, that all who are in Asia turned away from me, of whom are Phygelus and Hermogenes."},{"v":16,"t":"May the Lord grant mercy to the house of Onesiphorus, for he often refreshed me, and was not ashamed of my chain,"},{"v":17,"t":"but when he was in Rome, he sought me diligently and found me"},{"v":18,"t":"(the Lord grant to him to find the Lord’s mercy in that day); and in how many things he served at Ephesus, you know very well."}],"hr":[{"v":1,"t":"Pavao, apostol Krista Isusa voljom Božjom, po obećanju života, života u Kristu Isusu,"},{"v":2,"t":"Timoteju, ljubljenom sinu: milost, milosrđe i mir od Boga Oca i Krista Isusa, Gospodina našega."},{"v":3,"t":"Zahvalan sam Bogu, kojemu onamo od predaka čiste savjesti služim, dok te se neprestano spominjem u svojim molitvama noć i dan."},{"v":4,"t":"Sjetim se tvojih suza i zaželim vidjeti te da se napunim radosti"},{"v":5,"t":"imajući na pameti neprijetvornu vjeru koja je u tebi - onu vjeru koja je najprije prebivala u tvojoj baki Loidi i tvojoj majci Euniki, a uvjeren sam, i u tebi."},{"v":6,"t":"Poradi toga podsjećam te: raspiruj milosni dar Božji koji je u tebi po polaganju mojih ruku."},{"v":7,"t":"Jer nije nam Bog dao duha bojažljivosti, nego snage, ljubavi i razbora."},{"v":8,"t":"Ne stidi se stoga svjedočanstva za Gospodina našega, ni mene, sužnja njegova. Nego zlopati se zajedno sa mnom za evanđelje, po snazi Boga"},{"v":9,"t":"koji nas je spasio i pozvao pozivom svetim - ne po našim djelima, nego po svojem naumu i milosti koja nam je dana u Kristu Isusu prije vremena vjekovječnih,"},{"v":10,"t":"a očitovana je sada pojavkom Spasitelja našega Krista Isusa, koji obeskrijepi smrt i učini da zasja život i neraspadljivost - po evanđelju"},{"v":11,"t":"za koje sam ja postavljen propovjednikom, apostolom i učiteljem."},{"v":12,"t":"Poradi toga i ovo trpim, ali se ne stidim jer znam komu sam povjerovao i uvjeren sam da je on moćan poklad moj sačuvati za onaj Dan."},{"v":13,"t":"Uzorom neka ti budu zdrave riječi koje si od mene čuo u vjeri i ljubavi u Kristu Isusu."},{"v":14,"t":"Lijepi poklad čuvaj po Duhu Svetom koji prebiva u nama."},{"v":15,"t":"Napustiše me, to znaš, svi u Aziji, među njima i Figel i Hermogen."},{"v":16,"t":"Neka Gospodin milosrđem podari Oneziforov dom jer me često osvježivao i nije se stidio mojih okova,"},{"v":17,"t":"nego kad je bio u Rimu, brižljivo me potražio i našao."},{"v":18,"t":"Dao mu Gospodin naći milosrđe u Gospodina u onaj Dan! A koliko je usluga u Efezu iskazao, to ti najbolje znaš."}]},"2":{"fa":[{"v":1,"t":"پس تو‌ای فرزند من، در فیضی که در مسیح عیسی است زورآور باش."},{"v":2,"t":"و آنچه به شهود بسیار از من شنیدی، به مردمان امین بسپارکه قابل تعلیم دیگران هم باشند."},{"v":3,"t":"چون سپاهی نیکوی مسیح عیسی در تحمل زحمات شریک باش."},{"v":4,"t":"هیچ سپاهی خود را در امور روزگار گرفتارنمی سازد تا رضایت آنکه او را سپاهی ساخت بجوید."},{"v":5,"t":"و اگر کسی نیز پهلوانی کند، تاج را بدونمی دهند اگر به قانون پهلوانی نکرده باشد."},{"v":6,"t":"برزگری که محنت می‌کشد، باید اول نصیبی ازحاصل ببرد."},{"v":7,"t":"در آنچه می‌گویم تفکر کن زیراخداوند تو را در همه‌چیز فهم خواهد بخشید."},{"v":8,"t":"عیسی مسیح را بخاطر دار که از نسل داودبوده، از مردگان برخاست برحسب بشارت من،"},{"v":9,"t":"که در آن چون بدکار تا به بندها زحمت می‌کشم، لیکن کلام خدا بسته نمی شود."},{"v":10,"t":"و ازاین جهت همه زحمات را بخاطر برگزیدگان متحمل می‌شوم تا ایشان نیز نجاتی را که درمسیح عیسی است با جلال جاودانی تحصیل کنند."},{"v":11,"t":"این سخن امین است زیرا اگر با وی مردیم، با او زیست هم خواهیم کرد."},{"v":12,"t":"و اگرتحمل کنیم، با او سلطنت هم خواهیم کرد؛ وهرگاه او را انکار کنیم او نیز ما را انکار خواهدکرد."},{"v":13,"t":"اگر بی‌ایمان شویم، او امین می‌ماند زیراخود را انکار نمی تواند نمود."},{"v":14,"t":"این چیزها را به یاد ایشان آور و در حضورخداوند قدغن فرما که مجادله نکنند، زیرا هیچ سود نمی بخشد بلکه باعث هلاکت شنوندگان می‌باشد."},{"v":15,"t":"و سعی کن که خود را مقبول خداسازی، عاملی که خجل نشود و کلام خدا رابخوبی انجام دهد."},{"v":16,"t":"و از یاوه‌گویی های حرام اعراض نما زیرا که تا به فزونی بی‌دینی ترقی خواهد کرد."},{"v":17,"t":"و کلام ایشان، چون آکله می‌خورد و از آنجمله هیمیناوس و فلیطس می‌باشند"},{"v":18,"t":"که ایشان از حق برگشته، می‌گویندکه قیامت الان شده است و بعضی را از ایمان منحرف می‌سازند."},{"v":19,"t":"و لیکن بنیاد ثابت خدا قائم است و این مهر را دارد که «خداوند کسان خود رامی شناسد» و «هرکه نام مسیح را خواند، ازناراستی کناره جوید.»"},{"v":20,"t":"اما در خانه بزرگ نه فقطظروف طلا و نقره می‌باشد، بلکه چوبی و گلی نیز؛ اما آنها برای عزت و اینها برای ذلت."},{"v":21,"t":"پس اگرکسی خویشتن را از اینها طاهر سازد، ظرف عزت خواهد بود مقدس و نافع برای مالک خود ومستعد برای هر عمل نیکو."},{"v":22,"t":"اما از شهوات جوانی بگریز و با آنانی که ازقلب خالص نام خداوند را می‌خوانند، عدالت وایمان و محبت و سلامتی را تعاقب نما."},{"v":23,"t":"لیکن ازمسائل بیهوده و بی‌تادیب اعراض نما چون می‌دانی که نزاعها پدید می‌آورد."},{"v":24,"t":"اما بنده خدانباید نزاع کند، بلکه با همه کس ملایم و راغب به تعلیم و صابر در مشقت باشد،"},{"v":25,"t":"و با حلم مخالفین را تادیب نماید که شاید خدا ایشان راتوبه بخشد تا راستی را بشناسند."},{"v":26,"t":"تا از دام ابلیس باز به هوش آیند که به حسب اراده او صیداو شده‌اند."}],"en":[{"v":1,"t":"You therefore, my child, be strengthened in the grace that is in Christ Jesus."},{"v":2,"t":"The things which you have heard from me among many witnesses, commit the same things to faithful men who will be able to teach others also."},{"v":3,"t":"You therefore must endure hardship as a good soldier of Christ Jesus."},{"v":4,"t":"No soldier on duty entangles himself in the affairs of life, that he may please him who enrolled him as a soldier."},{"v":5,"t":"Also, if anyone competes in athletics, he isn’t crowned unless he has competed by the rules."},{"v":6,"t":"The farmer who labors must be the first to get a share of the crops."},{"v":7,"t":"Consider what I say, and may the Lord give you understanding in all things."},{"v":8,"t":"Remember Jesus Christ, risen from the dead, of the offspring of David, according to my Good News,"},{"v":9,"t":"in which I suffer hardship to the point of chains as a criminal. But God’s word isn’t chained."},{"v":10,"t":"Therefore I endure all things for the chosen ones’ sake, that they also may obtain the salvation which is in Christ Jesus with eternal glory."},{"v":11,"t":"This saying is trustworthy: “For if we died with him, we will also live with him."},{"v":12,"t":"If we endure, we will also reign with him. If we deny him, he also will deny us."},{"v":13,"t":"If we are faithless, he remains faithful; for he can’t deny himself.”"},{"v":14,"t":"Remind them of these things, charging them in the sight of the Lord that they don’t argue about words to no profit, to the subverting of those who hear."},{"v":15,"t":"Give diligence to present yourself approved by God, a workman who doesn’t need to be ashamed, properly handling the Word of Truth."},{"v":16,"t":"But shun empty chatter, for it will go further in ungodliness,"},{"v":17,"t":"and those words will consume like gangrene, of whom is Hymenaeus and Philetus:"},{"v":18,"t":"men who have erred concerning the truth, saying that the resurrection is already past, and overthrowing the faith of some."},{"v":19,"t":"However, God’s firm foundation stands, having this seal: “The Lord knows those who are his,” and, “Let every one who names the name of the Lord depart from unrighteousness.”"},{"v":20,"t":"Now in a large house there are not only vessels of gold and of silver, but also of wood and of clay. Some are for honor and some for dishonor."},{"v":21,"t":"If anyone therefore purges himself from these, he will be a vessel for honor, sanctified, and suitable for the master’s use, prepared for every good work."},{"v":22,"t":"Flee from youthful lusts; but pursue righteousness, faith, love, and peace with those who call on the Lord out of a pure heart."},{"v":23,"t":"But refuse foolish and ignorant questionings, knowing that they generate strife."},{"v":24,"t":"The Lord’s servant must not quarrel, but be gentle toward all, able to teach, patient,"},{"v":25,"t":"in gentleness correcting those who oppose him. Perhaps God may give them repentance leading to a full knowledge of the truth,"},{"v":26,"t":"and they may recover themselves out of the devil’s snare, having been taken captive by him to do his will."}],"hr":[{"v":1,"t":"Ti se dakle, dijete moje, jačaj milošću u Kristu Isusu"},{"v":2,"t":"i što si od mene po mnogim svjedocima čuo, to predaj vjernim ljudima koji će biti podobni i druge poučiti."},{"v":3,"t":"S njima se zlopati kao dobar vojnik Krista Isusa."},{"v":4,"t":"Tko vojuje, ne zapleće se u svagdanje poslove kako bi se vojskovođi svidio."},{"v":5,"t":"I natječe li se tko, ne ovjenčava se ako se zakonito ne natječe."},{"v":6,"t":"Ratar koji se trudi treba da prvi primi od uroda."},{"v":7,"t":"Shvati što govorim! Ta dat će ti Gospodin razum u svemu."},{"v":8,"t":"Spominji se Isusa Krista, uskrsla od mrtvih, od potomstva Davidova - po mojem evanđelju."},{"v":9,"t":"Za nj se ja zlopatim sve do okova, kao zločinac. Ali riječ Božja nije okovana!"},{"v":10,"t":"Stoga sve podnosim radi izabranih, da i oni postignu spasenje, spasenje u Kristu Isusu, zajedno s vječnom slavom."},{"v":11,"t":"Vjerodostojna je riječ: Ako s njime umrijesmo, s njime ćemo i živjeti."},{"v":12,"t":"Ako ustrajemo, s njime ćemo i kraljevati. Ako ga zaniječemo, i on će zanijekati nas."},{"v":13,"t":"Ako ne budemo vjerni, on vjeran ostaje. Ta ne može sebe zanijekati!"},{"v":14,"t":"Na to podsjećaj zaklinjući pred Bogom neka ne bude rječoborstva: ničemu ne koristi, a na propast je onima koji slušaju."},{"v":15,"t":"Uznastoj da kao prokušan staneš pred Boga kao radnik koji se nema čega stidjeti, koji ispravno reže riječ istine."},{"v":16,"t":"Svjetovnih se pak praznorječja kloni: sve će više provaljivati prema bezbožnosti"},{"v":17,"t":"i riječ će njihova kao rak-rana izgrizati. Od njih su Himenej i Filet,"},{"v":18,"t":"koji zastraniše od istine tvrdeći da je uskrsnuće već bilo te nekima prevraćaju vjeru."},{"v":19,"t":"Ipak čvrsti temelj Božji stoji - pod ovim je pečatom: Poznaje Gospodin one koji su njegovi i neka se kloni zloće tko god imenuje ime Gospodnje."},{"v":20,"t":"Pa u velikoj kući ima posuda ne samo zlatnih i srebrnih, nego i drvenih i glinenih; i jedne su časne, druge pak nečasne."},{"v":21,"t":"Očisti li se dakle tko od toga, bit će posuda časna, posvećena, korisna Gospodaru, za svako dobro djelo prikladna."},{"v":22,"t":"A mladenačkih se strastvenosti kloni! Teži za pravednošću, vjerom, ljubavlju, mirom sa svima koji iz čista srca prizivlju Gospodina."},{"v":23,"t":"Lude pak i neobuzdane raspre odbijaj znajući da rađaju svađama."},{"v":24,"t":"A sluga Gospodnji treba da se ne svađa, nego da bude nježan prema svima, sposoban poučavati, zlo podnositi,"},{"v":25,"t":"da s blagošću preodgaja protivnike, ne bi li ih Bog podario obraćenjem te spoznaju istinu"},{"v":26,"t":"i ponovno budu trijezni izvan zamke đavla koji ih drži robljem svoje volje."}]},"3":{"fa":[{"v":1,"t":"اما این را بدان که در ایام آخر زمانهای سخت پدید خواهد آمد،"},{"v":2,"t":"زیرا که مردمان، خودپرست خواهند بود و طماع ولاف‌زن و متکبر و بدگو و نامطیع والدین و ناسپاس و ناپاک"},{"v":3,"t":"و بی‌الفت و کینه دل و غیبت‌گو و ناپرهیزو بی‌مروت و متنفر از نیکویی"},{"v":4,"t":"و خیانت کار وتندمزاج و مغرور که عشرت را بیشتر از خدادوست می‌دارند؛"},{"v":5,"t":"که صورت دینداری دارند، لیکن قوت آن را انکار می‌کنند. از ایشان اعراض نما."},{"v":6,"t":"زیرا که از اینها هستند آنانی که به حیله داخل خانه‌ها گشته، زنان کم عقل را اسیر می‌کنندکه بار گناهان را می‌کشند و به انواع شهوات ربوده می‌شوند."},{"v":7,"t":"و دائم تعلیم می‌گیرند، لکن هرگز به معرفت راستی نمی توانند رسید."},{"v":8,"t":"و همچنان‌که ینیس و یمبریس با موسی مقاومت کردند، ایشان نیز با راستی مقاومت می‌کنند که مردم فاسدالعقل و مردود از ایمانند."},{"v":9,"t":"لیکن بیشتر ترقی نخواهندکرد زیرا که حماقت ایشان بر جمیع مردم واضح خواهد شد، چنانکه حماقت آنها نیز شد."},{"v":10,"t":"لیکن تو تعلیم و سیرت و قصد و ایمان وحلم و محبت و صبر مرا پیروی نمودی،"},{"v":11,"t":"وزحمات و آلام مرا مثل آنهایی که در انطاکیه وایقونیه و لستره بر من واقع شد، چگونه زحمات راتحمل می‌نمودم و خداوند مرا از همه رهایی داد."},{"v":12,"t":"و همه کسانی که می‌خواهند در مسیح عیسی به دینداری زیست کنند، زحمت خواهند کشید."},{"v":13,"t":"لیکن مردمان شریر و دغاباز در بدی ترقی خواهند کرد که فریبنده و فریب خورده می‌باشند."},{"v":14,"t":"اما تو در آنچه آموختی و ایمان آوردی قایم باش چونکه می‌دانی از چه کسان تعلیم یافتی،"},{"v":15,"t":"و اینکه از طفولیت کتب مقدسه را دانسته‌ای که می‌تواند تو را حکمت آموزدبرای نجات بوسیله ایمانی که بر مسیح عیسی است."},{"v":16,"t":"تمامی کتب از الهام خداست و بجهت تعلیم و تنبیه و اصلاح و تربیت در عدالت مفیداست،"},{"v":17,"t":"تا مرد خدا کامل و بجهت هر عمل نیکوآراسته بشود."}],"en":[{"v":1,"t":"But know this: that in the last days, grievous times will come."},{"v":2,"t":"For men will be lovers of self, lovers of money, boastful, arrogant, blasphemers, disobedient to parents, unthankful, unholy,"},{"v":3,"t":"without natural affection, unforgiving, slanderers, without self-control, fierce, not lovers of good,"},{"v":4,"t":"traitors, headstrong, conceited, lovers of pleasure rather than lovers of God,"},{"v":5,"t":"holding a form of godliness but having denied its power. Turn away from these, also."},{"v":6,"t":"For some of these are people who creep into houses and take captive gullible women loaded down with sins, led away by various lusts,"},{"v":7,"t":"always learning and never able to come to the knowledge of the truth."},{"v":8,"t":"Even as Jannes and Jambres opposed Moses, so these also oppose the truth, men corrupted in mind, who concerning the faith are rejected."},{"v":9,"t":"But they will proceed no further. For their folly will be evident to all men, as theirs also came to be."},{"v":10,"t":"But you followed my teaching, conduct, purpose, faith, patience, love, steadfastness,"},{"v":11,"t":"persecutions, and sufferings—those things that happened to me at Antioch, Iconium, and Lystra. I endured those persecutions. The Lord delivered me out of them all."},{"v":12,"t":"Yes, and all who desire to live godly in Christ Jesus will suffer persecution."},{"v":13,"t":"But evil men and impostors will grow worse and worse, deceiving and being deceived."},{"v":14,"t":"But you remain in the things which you have learned and have been assured of, knowing from whom you have learned them."},{"v":15,"t":"From infancy, you have known the holy Scriptures which are able to make you wise for salvation through faith which is in Christ Jesus."},{"v":16,"t":"Every Scripture is God-breathed and profitable for teaching, for reproof, for correction, and for instruction in righteousness,"},{"v":17,"t":"that each person who belongs to God may be complete, thoroughly equipped for every good work."}],"hr":[{"v":1,"t":"A ovo znaj: u posljednjim danima nastat će teška vremena."},{"v":2,"t":"Ljudi će doista biti sebeljupci, srebroljupci, preuzetnici, oholice, hulitelji, roditeljima neposlušni, nezahvalnici, bezbožnici,"},{"v":3,"t":"bešćutnici, nepomirljivci, klevetnici, neobuzdanici, goropadnici, neljubitelji dobra,"},{"v":4,"t":"izdajice, brzopletnici, naduti, ljubitelji užitka više nego ljubitelji Boga."},{"v":5,"t":"Imaju obličje pobožnosti, ali snage su se njezine odrekli. I njih se kloni!"},{"v":6,"t":"Od njih su doista oni što se uvlače u kuće i zarobljuju ženice, natovarene grijesima, vodane najrazličitijim strastima:"},{"v":7,"t":"one uvijek uče, a nikako ne mogu doći do spoznaje istine."},{"v":8,"t":"Kao što se Janes i Jambres suprotstaviše Mojsiju, tako se i ovi, ljudi pokvarena uma, u vjeri neprokušani, suprotstavljaju istini."},{"v":9,"t":"Ali neće više napredovati jer bezumlje će ovih postati očito, kako se to i onima dogodilo."},{"v":10,"t":"A ti si pošao za nmom u poučavanju, u ponašanju, u naumu, u vjeri, u strpljivosti, u ljubavi, u postojanosti;"},{"v":11,"t":"u progonstvima, u patnjama koje su me zadesile u Antiohiji, u Ikoniju, u Listri. Kakva li sam progonstva podnio! I iz svih me izbavio Gospodin!"},{"v":12,"t":"A i svi koji hoće živjeti pobožno u Kristu Isusu, bit će progonjeni."},{"v":13,"t":"Zli pak ljudi i vračari napredovat će sve više u zlu - kao zavodnici i zavedeni."},{"v":14,"t":"Ti, naprotiv, ostani u onome u čemu si poučen i čemu si vjeru dao, svjestan od koga si sve poučen"},{"v":15,"t":"i da od malena poznaješ Sveta pisma koja su vrsna učiniti te mudrim tebi na spasenje po vjeri, vjeri u Kristu Isusu."},{"v":16,"t":"Sve Pismo, bogoduho, korisno je za poučavanje, uvjeravanje, popravljanje, odgajanje u pravednosti,"},{"v":17,"t":"da čovjek Božji bude vrstan, za svako dobro djelo podoban."}]},"4":{"fa":[{"v":1,"t":"تو را در حضور خدا و مسیح عیسی که برزندگان و مردگان داوری خواهد کرد قسم می‌دهم و به ظهور وملکوت او"},{"v":2,"t":"که به کلام موعظه کنی و در فرصت و غیر فرصت مواظب باشی و تنبیه و توبیخ و نصیحت نمایی باکمال تحمل و تعلیم."},{"v":3,"t":"زیرا ایامی می‌آید که تعلیم صحیح را متحمل نخواهند شد، بلکه برحسب شهوات خود خارش گوشها داشته، معلمان را برخود فراهم خواهند‌آورد،"},{"v":4,"t":"و گوشهای خود رااز راستی برگردانیده، به سوی افسانه‌ها خواهندگرایید."},{"v":5,"t":"لیکن تو در همه‌چیز هشیار بوده، متحمل زحمات باش و عمل مبشر را بجا آور وخدمت خود را به‌کمال رسان."},{"v":6,"t":"زیرا که من الان ریخته می‌شوم و وقت رحلت من رسیده است."},{"v":7,"t":"به جنگ نیکو جنگ کرده‌ام و دوره خود را به‌کمال رسانیده، ایمان رامحفوظ داشته‌ام."},{"v":8,"t":"بعد از این تاج عدالت برای من حاضر شده است که خداوند داور عادل در آن روز به من خواهد داد؛ و نه به من فقط بلکه نیز به همه کسانی که ظهور او را دوست می‌دارند."},{"v":9,"t":"سعی کن که به زودی نزد من آیی،"},{"v":10,"t":"زیرا که دیماس برای محبت این جهان حاضر مرا ترک کرده، به تسالونیکی رفته است و کریسکیس به غلاطیه و تیطس به دلماطیه."},{"v":11,"t":"لوقا تنها با من است. مرقس را برداشته، با خود بیاور زیرا که مرابجهت خدمت مفید است."},{"v":12,"t":"اما تیخیکس را به افسس فرستادم."},{"v":13,"t":"ردایی را که در تروآس نزدکرپس گذاشتم، وقت آمدنت بیاور و کتب را نیز وخصوص رقوق را."},{"v":14,"t":"اسکندر مسکر با من بسیاربدیها کرد. خداوند او را بحسب افعالش جزاخواهد داد."},{"v":15,"t":"و تو هم از او باحذر باش زیرا که باسخنان ما بشدت مقاومت نمود."},{"v":16,"t":"در محاجه اول من، هیچ‌کس با من حاضر نشد بلکه همه مراترک کردند. مباد که این بر ایشان محسوب شود."},{"v":17,"t":"لیکن خداوند با من ایستاده، به من قوت داد تاموعظه بوسیله من به‌کمال رسد و تمامی امت هابشنوند و از دهان شیر رستم."},{"v":18,"t":"و خداوند مرا ازهر کار بد خواهد رهانید و تا به ملکوت آسمانی خود نجات خواهد داد. او را تا ابدالاباد جلال باد. آمین."},{"v":19,"t":"فرسکا و اکیلا و اهل خانه انیسیفورس راسلام رسان."},{"v":20,"t":"ارستس در قرنتس ماند؛ اماترفیمس را در میلیتس بیمار واگذاردم."},{"v":21,"t":"سعی کن که قبل از زمستان بیایی. افبولس و پودیس ولینس و کلادیه و همه برادران تو را سلام می‌رسانند."},{"v":22,"t":"عیسی مسیح خداوند با روح توباد. فیض بر شما باد. آمین."}],"en":[{"v":1,"t":"I command you therefore before God and the Lord Jesus Christ, who will judge the living and the dead at his appearing and his Kingdom:"},{"v":2,"t":"preach the word; be urgent in season and out of season; reprove, rebuke, and exhort with all patience and teaching."},{"v":3,"t":"For the time will come when they will not listen to the sound doctrine, but having itching ears, will heap up for themselves teachers after their own lusts,"},{"v":4,"t":"and will turn away their ears from the truth, and turn away to fables."},{"v":5,"t":"But you be sober in all things, suffer hardship, do the work of an evangelist, and fulfill your ministry."},{"v":6,"t":"For I am already being offered, and the time of my departure has come."},{"v":7,"t":"I have fought the good fight. I have finished the course. I have kept the faith."},{"v":8,"t":"From now on, the crown of righteousness is stored up for me, which the Lord, the righteous judge, will give to me on that day; and not to me only, but also to all those who have loved his appearing."},{"v":9,"t":"Be diligent to come to me soon,"},{"v":10,"t":"for Demas left me, having loved this present world, and went to Thessalonica; Crescens to Galatia; and Titus to Dalmatia."},{"v":11,"t":"Only Luke is with me. Take Mark and bring him with you, for he is useful to me for service."},{"v":12,"t":"But I sent Tychicus to Ephesus."},{"v":13,"t":"Bring the cloak that I left at Troas with Carpus when you come—and the books, especially the parchments."},{"v":14,"t":"Alexander the coppersmith did much evil to me. The Lord will repay him according to his deeds."},{"v":15,"t":"Beware of him, for he greatly opposed our words."},{"v":16,"t":"At my first defense, no one came to help me, but all left me. May it not be held against them."},{"v":17,"t":"But the Lord stood by me and strengthened me, that through me the message might be fully proclaimed, and that all the Gentiles might hear. So I was delivered out of the mouth of the lion."},{"v":18,"t":"And the Lord will deliver me from every evil work and will preserve me for his heavenly Kingdom. To him be the glory forever and ever. Amen."},{"v":19,"t":"Greet Prisca and Aquila, and the house of Onesiphorus."},{"v":20,"t":"Erastus remained at Corinth, but I left Trophimus at Miletus sick."},{"v":21,"t":"Be diligent to come before winter. Eubulus salutes you, as do Pudens, Linus, Claudia, and all the brothers."},{"v":22,"t":"The Lord Jesus Christ be with your spirit. Grace be with you. Amen."}],"hr":[{"v":1,"t":"Zaklinjem te pred Bogom i Kristom Isusom, koji će suditi žive i mrtve, zaklinjem te pojavkom njegovim i kraljevstvom njegovim:"},{"v":2,"t":"propovijedaj Riječ, uporan budi - bilo to zgodno ili nezgodno - uvjeravaj, prijeti, zapovijedaj sa svom strpljivošću i poukom."},{"v":3,"t":"Jer doći će vrijeme kad ljudi neće podnositi zdrava nauka nego će sebi po vlastitim požudama nagomilavati učitelje kako im godi ušima;"},{"v":4,"t":"od istine će uho odvraćati, a bajkama se priklanjati."},{"v":5,"t":"Ti, naprotiv, budi trijezan u svemu, zlopati se, djelo izvrši blagovjesničko, služenje svoje posve ispuni!"},{"v":6,"t":"Jer ja se već prinosim za žrtvu ljevanicu, prispjelo je vrijeme moga odlaska."},{"v":7,"t":"Dobar sam boj bio, trku završio, vjeru sačuvao."},{"v":8,"t":"Stoga, pripravljen mi je vijenac pravednosti kojim će mi u onaj Dan uzvratiti Gospodin, pravedan sudac; ne samo meni, nego i svima koji s ljubavlju čekaju njegov pojavak."},{"v":9,"t":"Nastoj što prije doći k meni!"},{"v":10,"t":"Jer Dema me, zaljubljen u sadašnji svijet, napustio i otišao u Solun; Krescencije u Galaciju, Tit u Dalmaciju."},{"v":11,"t":"Luka je jedini sa mnom. Marka uzmi i dovedi sa sobom jer mi je koristan za služenje."},{"v":12,"t":"Tihika sam poslao u Efez."},{"v":13,"t":"Kabanicu koju ostavih u Troadi kod Karpa, kada dođeš, donesi. I knjige, osobito pergamene."},{"v":14,"t":"Aleksandar kovač nanio mi je mnogo zla. Uzvratio mu Gospodin po njegovim djelima!"},{"v":15,"t":"Njega se i ti čuvaj jer se veoma usprotivio našim riječima."},{"v":16,"t":"Za prve moje obrane nitko ne bijaše uza me, svi me napustiše. Ne uračunalo im se!"},{"v":17,"t":"Ali Gospodin je stajao uza me, on me krijepio da se po meni potpuno razglasi Poruka te je čuju svi narodi; i izbavljen sam iz usta lavljih."},{"v":18,"t":"Izbavit će me Gospodin od svakoga zla djela i spasiti za svoje nebesko kraljevstvo. Njemu slava u vijeke vjekova! Amen!"},{"v":19,"t":"Pozdravi Prisku i Akvilu i Oneziforov dom!"},{"v":20,"t":"Erast osta u Korintu, a Trofima ostavih u Miletu bolesna."},{"v":21,"t":"Nastoj doći prije zime. Pozdravlja te Eubul, Pudencije, Lino, Klaudija i sva braća."},{"v":22,"t":"Gospodin s duhom tvojim. Milost s vama!"}]}},"TIT":{"1":{"fa":[{"v":1,"t":"پولس، غلام خدا و رسول عیسی مسیح برحسب ایمان برگزیدگان خدا و معرفت آن راستی که در دینداری است،"},{"v":2,"t":"به امید حیات جاودانی که خدایی که دروغ نمی تواند گفت، اززمانهای ازلی وعده آن را داد،"},{"v":3,"t":"اما در زمان معین، کلام خود را ظاهر کرد به موعظه‌ای که برحسب حکم نجات‌دهنده ما خدا به من سپرده شد،"},{"v":4,"t":"تیطس را که فرزند حقیقی من برحسب ایمان عام است، فیض و رحمت و سلامتی از جانب خدای پدرو نجات‌دهنده ما عیسی مسیح خداوند باد."},{"v":5,"t":"بدین جهت تو را در کریت واگذاشتم تا آنچه را که باقی‌مانده است اصلاح نمایی و چنانکه من به تو امر نمودم، کشیشان در هر شهر مقرر کنی."},{"v":6,"t":"اگر کسی بی‌ملامت و شوهر یک زن باشد که فرزندان مومن دارد، بری از تهمت فجور و تمرد،"},{"v":7,"t":"زیرا که اسقف می‌باید چون وکیل خدابی ملامت باشد و خودرای یا تندمزاج یا میگساریا زننده یا طماع سود قبیح نباشد،"},{"v":8,"t":"بلکه مهمان دوست و خیردوست و خرداندیش و عادل ومقدس و پرهیزکار؛"},{"v":9,"t":"و متمسک به کلام امین برحسب تعلیمی که یافته تا بتواند به تعلیم صحیح نصیحت کند و مخالفان را توبیخ نماید."},{"v":10,"t":"زیرا که یاوه‌گویان و فریبندگان، بسیار ومتمرد می‌باشند، علی الخصوص آنانی که از اهل ختنه هستند؛"},{"v":11,"t":"که دهان ایشان را باید بست زیراخانه‌ها را بالکل واژگون می‌سازند و برای سودقبیح، تعالیم ناشایسته می‌دهند."},{"v":12,"t":"یکی از ایشان که نبی خاص ایشان است، گفته است که «اهل کریت همیشه دروغگو و وحوش شریر وشکم پرست بی‌کاره می‌باشند.»"},{"v":13,"t":"این شهادت راست است؛ از این جهت ایشان را به سختی توبیخ فرما تا در ایمان، صحیح باشند،"},{"v":14,"t":"و گوش نگیرند به افسانه های یهود و احکام مردمانی که ازراستی انحراف می‌جویند."},{"v":15,"t":"هرچیز برای پاکان پاک است، لیکن آلودگان و بی‌ایمانان را هیچ‌چیزپاک نیست، بلکه فهم و ضمیر ایشان نیز ملوث است؛"},{"v":16,"t":"مدعی معرفت خدا می‌باشند، اما به افعال خود او را انکار می‌کنند، چونکه مکروه ومتمرد هستند و بجهت هر عمل نیکو مردود."}],"en":[{"v":1,"t":"Paul, a servant of God and an apostle of Jesus Christ, according to the faith of God’s chosen ones and the knowledge of the truth which is according to godliness,"},{"v":2,"t":"in hope of eternal life, which God, who can’t lie, promised before time began;"},{"v":3,"t":"but in his own time revealed his word in the message with which I was entrusted according to the commandment of God our Savior,"},{"v":4,"t":"to Titus, my true child according to a common faith: Grace, mercy, and peace from God the Father and the Lord Jesus Christ our Savior."},{"v":5,"t":"I left you in Crete for this reason, that you would set in order the things that were lacking and appoint elders in every city, as I directed you—"},{"v":6,"t":"if anyone is blameless, the husband of one wife, having children who believe, who are not accused of loose or unruly behavior."},{"v":7,"t":"For the overseer must be blameless, as God’s steward, not self-pleasing, not easily angered, not given to wine, not violent, not greedy for dishonest gain;"},{"v":8,"t":"but given to hospitality, a lover of good, sober minded, fair, holy, self-controlled,"},{"v":9,"t":"holding to the faithful word which is according to the teaching, that he may be able to exhort in the sound doctrine, and to convict those who contradict him."},{"v":10,"t":"For there are also many unruly men, vain talkers and deceivers, especially those of the circumcision,"},{"v":11,"t":"whose mouths must be stopped: men who overthrow whole houses, teaching things which they ought not, for dishonest gain’s sake."},{"v":12,"t":"One of them, a prophet of their own, said, “Cretans are always liars, evil beasts, and idle gluttons.”"},{"v":13,"t":"This testimony is true. For this cause, reprove them sharply, that they may be sound in the faith,"},{"v":14,"t":"not paying attention to Jewish fables and commandments of men who turn away from the truth."},{"v":15,"t":"To the pure, all things are pure, but to those who are defiled and unbelieving, nothing is pure; but both their mind and their conscience are defiled."},{"v":16,"t":"They profess that they know God, but by their deeds they deny him, being abominable, disobedient, and unfit for any good work."}],"hr":[{"v":1,"t":"Pavao, sluga Božji i apostol Isusa Krista poradi vjere izabranika Božjih i spoznanja istine usmjerene k pobožnosti"},{"v":2,"t":"u nadi života vječnoga što ga, prije vremena vjekovječnih, obeća Bog, On koji ne laže,"},{"v":3,"t":"a u svoje doba očitova riječ svoju u propovijedanju koje je meni povjereno po odredbi Spasitelja našega, Boga:"},{"v":4,"t":"Titu, pravomu sinu po zajedničkoj vjeri, milost i mir od Boga i Krista Isusa, Spasitelja našega!"},{"v":5,"t":"Poradi toga ostavih te na Kreti da urediš preostalo te po gradovima postaviš starješine kako sam ti ja odredio:"},{"v":6,"t":"je li tko besprigovoran, jedne žene muž, jesu li mu djeca vjernici i ne pod optužbom raskalašenosti ili nepokorna..."},{"v":7,"t":"Jer nadstojnik kao Božji upravitelj treba da bude besprigovoran: ne samoživ, ne jedljiv, ne vinu sklon, ni nasilju, ni prljavu dobitku,"},{"v":8,"t":"nego gostoljubiv, ljubitelj dobra, razuman, pravedan, svet, uzdržljiv,"},{"v":9,"t":"priljubljen uz vjerodostojnu riječ nauka da može i hrabriti u zdravom nauku i uvjeravati protivnike."},{"v":10,"t":"Jer mnogi su nepokorni, praznorječni i zavodnici, ponajpače oni iz obrezanja."},{"v":11,"t":"Njima treba začepiti usta jer cijele domove prevraćaju naučavajući što ne bi smjeli, i to poradi prljava dobitka."},{"v":12,"t":"Reče netko od njih, njihov vlastiti prorok: “Krećani uvijek lašci, opake zvijeri, trbusi dangubni.”"},{"v":13,"t":"Svjedočanstvo je to istinito. Zato ih karaj oštro da budu zdravi u vjeri,"},{"v":14,"t":"da ne prianjaju uza židovske bajke i propise ljudi koji se odvraćaju od istine."},{"v":15,"t":"Sve je čisto čistima; okaljanima pak i nevjernima ništa čisto, nego su im okaljani i razum i savjest."},{"v":16,"t":"Ispovijedaju da Boga poznaju, ali djelima ga niječu - odvratni, neposlušni i za koje god dobro djelo nepodesni."}]},"2":{"fa":[{"v":1,"t":"اما تو سخنان شایسته تعلیم صحیح را بگو:"},{"v":2,"t":"که مردان پیر، هشیار و باوقار وخرداندیش و در ایمان و محبت و صبر، صحیح باشند."},{"v":3,"t":"همچنین زنان پیر، در سیرت متقی باشند و نه غیبت‌گو و نه بنده شراب زیاده بلکه معلمات تعلیم نیکو،"},{"v":4,"t":"تا زنان جوان را خرد بیاموزند که شوهردوست و فرزنددوست باشند،"},{"v":5,"t":"وخرداندیش و عفیفه و خانه نشین و نیکو و مطیع شوهران خود که مبادا کلام خدا متهم شود."},{"v":6,"t":"و به همین نسق جوانان را نصیحت فرما تا خرداندیش باشند."},{"v":7,"t":"و خود را در همه‌چیز نمونه اعمال نیکو بسازو در تعلیم خود صفا و وقار و اخلاص را بکار بر،"},{"v":8,"t":"و کلام صحیح بی‌عیب را تا دشمن چونکه فرصت بد‌گفتن در حق ما نیابد، خجل شود."},{"v":9,"t":"غلامان را نصیحت نما که آقایان خود رااطاعت کنند و در هر امر ایشان را راضی سازند ونقیض گو نباشند؛"},{"v":10,"t":"و دزدی نکنند بلکه کمال دیانت را ظاهر سازند تا تعلیم نجات‌دهنده ما خدارا در هر چیز زینت دهند."},{"v":11,"t":"زیرا که فیض خدا که برای همه مردم نجات‌بخش است، ظاهر شده،"},{"v":12,"t":"ما را تادیب می‌کند که بی‌دینی و شهوات دنیوی را ترک کرده، با خرداندیشی و عدالت و دینداری در این جهان زیست کنیم."},{"v":13,"t":"و آن امید مبارک و تجلی جلال خدای عظیم و نجات‌دهنده خود ما عیسی مسیح را انتظار کشیم،"},{"v":14,"t":"که خود را در راه ما فدا ساخت تا ما را از هر ناراستی برهاند و امتی برای خودطاهر سازد که ملک خاص او و غیور در اعمال نیکو باشند."},{"v":15,"t":"این را بگو و نصیحت فرما و درکمال اقتدار توبیخ نما و هیچ‌کس تو را حقیرنشمارد."}],"en":[{"v":1,"t":"But say the things which fit sound doctrine,"},{"v":2,"t":"that older men should be temperate, sensible, sober minded, sound in faith, in love, and in perseverance,"},{"v":3,"t":"and that older women likewise be reverent in behavior, not slanderers nor enslaved to much wine, teachers of that which is good,"},{"v":4,"t":"that they may train the young wives to love their husbands, to love their children,"},{"v":5,"t":"to be sober minded, chaste, workers at home, kind, being in subjection to their own husbands, that God’s word may not be blasphemed."},{"v":6,"t":"Likewise, exhort the younger men to be sober minded."},{"v":7,"t":"In all things show yourself an example of good works. In your teaching, show integrity, seriousness, incorruptibility,"},{"v":8,"t":"and soundness of speech that can’t be condemned, that he who opposes you may be ashamed, having no evil thing to say about us."},{"v":9,"t":"Exhort servants to be in subjection to their own masters and to be well-pleasing in all things, not contradicting,"},{"v":10,"t":"not stealing, but showing all good fidelity, that they may adorn the doctrine of God, our Savior, in all things."},{"v":11,"t":"For the grace of God has appeared, bringing salvation to all men,"},{"v":12,"t":"instructing us to the intent that, denying ungodliness and worldly lusts, we would live soberly, righteously, and godly in this present age;"},{"v":13,"t":"looking for the blessed hope and appearing of the glory of our great God and Savior, Jesus Christ,"},{"v":14,"t":"who gave himself for us, that he might redeem us from all iniquity and purify for himself a people for his own possession, zealous for good works."},{"v":15,"t":"Say these things and exhort and reprove with all authority. Let no one despise you."}],"hr":[{"v":1,"t":"Ti, naprotiv, govori što se priliči zdravu nauku:"},{"v":2,"t":"starci da budu trijezni, ozbiljni, razumni, zdrave vjere, ljubavi, postojanosti;"},{"v":3,"t":"starice isto tako - vladanja kakvo dolikuje svetima: ne klevetnice, ne ropkinje mnogog vina, nego učiteljice dobra"},{"v":4,"t":"da urazumljuju mlađe neka ljube svoje muževe, djecu,"},{"v":5,"t":"neka budu razumne, čiste, kućevne, dobre, podložne svojim muževima da se riječ Božja ne bi pogrđivala."},{"v":6,"t":"Mladiće isto tako potiči da budu razumni."},{"v":7,"t":"U svemu se pokaži uzorom dobrih djela: u poučavanju - nepokvarljivost, ozbiljnost,"},{"v":8,"t":"riječ zdrava, besprigovorna da se onaj nasuprot postidi nemajući o nama reći ništa zlo."},{"v":9,"t":"Robovi neka se svojim gospodarima u svemu podlažu, ugađaju im, ne proturječe,"},{"v":10,"t":"ne pronevjeruju, nego neka im iskazuju svaku dobru vjernost da u svemu budu ures nauku Spasitelja našega, Boga."},{"v":11,"t":"Pojavila se doista milost Božja, spasiteljica svih ljudi;"},{"v":12,"t":"odgojila nas da se odreknemo bezbožnosti i svjetovnih požuda te razumno, pravedno i pobožno živimo u sadašnjem svijetu,"},{"v":13,"t":"iščekujući blaženu nadu i pojavak slave velikoga Boga i Spasitelja našega Isusa Krista."},{"v":14,"t":"On sebe dade za nas da nas otkupi od svakoga bezakonja i očisti sebi Narod izabrani koji revnuje oko dobrih djela."},{"v":15,"t":"To govori, zapovijedaj, karaj sa svom vlašću. Nitko neka te ne prezire."}]},"3":{"fa":[{"v":1,"t":"بیاد ایشان آور که حکام و سلاطین رااطاعت کنند و فرمانبرداری نمایند و برای هرکار نیکو مستعد باشند،"},{"v":2,"t":"و هیچ‌کس را بدنگویند و جنگجو نباشند بلکه ملایم و کمال حلم را با جمیع مردم به‌جا آورند."},{"v":3,"t":"زیرا که ما نیز سابق بی‌فهم و نافرمانبردار وگمراه و بنده انواع شهوات و لذات بوده، در خبث و حسد بسر می‌بردیم که لایق نفرت بودیم و بریکدیگر بغض می‌داشتیم."},{"v":4,"t":"لیکن چون مهربانی ولطف نجات‌دهنده ما خدا ظاهر شد،"},{"v":5,"t":"نه به‌سبب اعمالی که ما به عدالت کرده بودیم، بلکه محض رحمت خود ما را نجات داد به غسل تولد تازه وتازگی‌ای که از روح‌القدس است؛"},{"v":6,"t":"که او را به ما به دولتمندی افاضه نمود، به توسط نجات‌دهنده ماعیسی مسیح،"},{"v":7,"t":"تا به فیض او عادل شمرده شده، وارث گردیم بحسب امید حیات جاودانی."},{"v":8,"t":"این سخن امین است و در این امور می‌خواهم تو قدغن بلیغ فرمایی تا آنانی که به خدا ایمان آورند، بکوشند که در اعمال نیکو مواظبت نمایند، زیرا که این امور برای انسان نیکو و مفیداست."},{"v":9,"t":"و از مباحثات نامعقول و نسب نامه‌ها و نزاعهاو جنگهای شرعی اعراض نما زیرا که بی‌ثمر وباطل است."},{"v":10,"t":"و از کسی‌که از اهل بدعت باشد، بعد از یک دو نصیحت اجتناب نما،"},{"v":11,"t":"چون می‌دانی که چنین کس مرتد و از خود ملزم شده درگناه رفتار می‌کند."},{"v":12,"t":"وقتی که ارتیماس یا تیخیکس را نزد توفرستم، سعی کن که در نیکوپولیس نزد من آیی زیرا که عزیمت دارم زمستان را در آنجا بسر برم."},{"v":13,"t":"زیناس خطیب و اپلس را در سفر ایشان به سعی امداد کن تا محتاج هیچ‌چیز نباشند."},{"v":14,"t":"و کسان ما نیز تعلیم بگیرند که در کارهای نیکومشغول باشند برای رفع احتیاجات ضروری، تابی ثمر نباشند."},{"v":15,"t":"جمیع رفقای من تو را سلام می‌رسانند و آنانی را که از روی ایمان ما رادوست می‌دارند سلام رسان. فیض با همگی شماباد. آمین."}],"en":[{"v":1,"t":"Remind them to be in subjection to rulers and to authorities, to be obedient, to be ready for every good work,"},{"v":2,"t":"to speak evil of no one, not to be contentious, to be gentle, showing all humility toward all men."},{"v":3,"t":"For we were also once foolish, disobedient, deceived, serving various lusts and pleasures, living in malice and envy, hateful, and hating one another."},{"v":4,"t":"But when the kindness of God our Savior and his love toward mankind appeared,"},{"v":5,"t":"not by works of righteousness which we did ourselves, but according to his mercy, he saved us through the washing of regeneration and renewing by the Holy Spirit,"},{"v":6,"t":"whom he poured out on us richly through Jesus Christ our Savior;"},{"v":7,"t":"that being justified by his grace, we might be made heirs according to the hope of eternal life."},{"v":8,"t":"This saying is faithful, and concerning these things I desire that you insist confidently, so that those who have believed God may be careful to maintain good works. These things are good and profitable to men;"},{"v":9,"t":"but shun foolish questionings, genealogies, strife, and disputes about the law; for they are unprofitable and vain."},{"v":10,"t":"Avoid a factious man after a first and second warning,"},{"v":11,"t":"knowing that such a one is perverted and sinful, being self-condemned."},{"v":12,"t":"When I send Artemas to you, or Tychicus, be diligent to come to me to Nicopolis, for I have determined to winter there."},{"v":13,"t":"Send Zenas the lawyer and Apollos on their journey speedily, that nothing may be lacking for them."},{"v":14,"t":"Let our people also learn to maintain good works to meet necessary needs, that they may not be unfruitful."},{"v":15,"t":"All who are with me greet you. Greet those who love us in faith. Grace be with you all. Amen."}],"hr":[{"v":1,"t":"Podsjećaj ih da se podlažu poglavarstvima, vlastima, da slušaju, da budu spremni na svako dobro djelo,"},{"v":2,"t":"nikoga da ne pogrđuju, da budu neratoborni, popustljivi, da očituju svaku blagost prema svim ljudima."},{"v":3,"t":"Jer i mi nekoć bijasmo nerazumni, nepokorni, lutalice, robovi raznih požuda i naslada, živjeli smo u zlu i zavisti, odvratni bili, mrzili jedni druge."},{"v":4,"t":"Ali kad se pojavila dobrostivost i čovjekoljublje Spasitelja našega, Boga,"},{"v":5,"t":"on nas spasi ne po djelima što ih u pravednosti mi učinismo, nego po svojem milosrđu: kupelji novoga rođenja i obnavljanja po Duhu Svetom"},{"v":6,"t":"koga bogato izli na nas po Isusu Kristu, Spasitelju našemu,"},{"v":7,"t":"da opravdani njegovom milošću budemo, po nadi, baštinici života vječnoga."},{"v":8,"t":"Vjerodostojna je ovo riječ i hoću da to uporno tvrdiš te da oni koji su povjerovali Bogu uznastoje prednjačiti dobrim djelima. To je dobro i korisno ljudima."},{"v":9,"t":"A ludih se raspra, i rodoslovlja, i svađa, i sukoba zakonskih kloni: beskorisni su i isprazni."},{"v":10,"t":"S krivovjercem nakon prvoga i drugog upozorenja prekini"},{"v":11,"t":"znajući da je izopačen i da griješi: on sam sebe osuđuje."},{"v":12,"t":"Kad pošaljem k tebi Artemu ili Tihika, požuri se k meni u Nikopol jer sam odlučio ondje prezimiti."},{"v":13,"t":"Zenu, pravnika, i Apolona brižljivo opremi da im ništa ne ponestane."},{"v":14,"t":"A i naši neka se uče prednjačiti dobrim djelima u životnim potrebama da ne budu neplodni."},{"v":15,"t":"Pozdravljaju te svi koji su sa mnom. Pozdravi one koji nas ljube u vjeri. Milost sa svima vama!"}]}},"PHM":{"1":{"fa":[{"v":1,"t":"پولس، اسیر مسیح عیسی و تیموتاوس برادر، به فلیمون عزیز و همکار ما"},{"v":2,"t":"و به اپفیه محبوبه و ارخپس همسپاه ما به کلیسایی که در خانه ات می‌باشد."},{"v":3,"t":"فیض و سلامتی از جانب پدر ما خدا وعیسی مسیح خداوند با شما باد."},{"v":4,"t":"خدای خود را شکر می‌کنم و پیوسته تو رادر دعاهای خود یاد می‌آورم"},{"v":5,"t":"چونکه ذکرمحبت و ایمان تو را شنیده‌ام که به عیسی خداوندو به همه مقدسین داری،"},{"v":6,"t":"تا شراکت ایمانت موثرشود در معرفت کامل هر نیکویی که در ما است برای مسیح عیسی."},{"v":7,"t":"زیرا که مرا خوشی کامل وتسلی رخ نمود از محبت تو از آنرو که دلهای مقدسین از تو‌ای برادر استراحت می‌پذیرند."},{"v":8,"t":"بدین جهت هرچند در مسیح کمال جسارت را دارم که به آنچه مناسب است تو را حکم دهم،"},{"v":9,"t":"لیکن برای محبت، سزاوارتر آن است که التماس نمایم، هرچند مردی چون پولس پیر والان اسیر مسیح عیسی نیز می‌باشم."},{"v":10,"t":"پس تو را التماس می‌کنم درباره فرزند خود انیسیمس که در زنجیرهای خود او را تولید نمودم،"},{"v":11,"t":"که سابق او برای تو بی‌فایده بود، لیکن الحال تو را و مرافایده مند می‌باشد؛"},{"v":12,"t":"که او را نزد تو پس می‌فرستم. پس تو او را بپذیر که جان من است."},{"v":13,"t":"و من می‌خواستم که او را نزد خود نگاه دارم تابه عوض تو مرا در زنجیرهای انجیل خدمت کند،"},{"v":14,"t":"اما نخواستم کاری بدون رای تو کرده باشم تااحسان تو از راه اضطرار نباشد، بلکه از روی اختیار."},{"v":15,"t":"زیرا که شاید بدین جهت ساعتی از توجدا شد تا او را تا به ابد دریابی."},{"v":16,"t":"لیکن بعد از این نه چون غلام بلکه فوق از غلام یعنی برادر عزیزخصوص به من اما چند مرتبه زیادتر به تو هم درجسم و هم در خداوند."},{"v":17,"t":"پس هرگاه مرا رفیق می‌دانی، او را چون من قبول فرما."},{"v":18,"t":"اما اگرضرری به تو رسانیده باشد یا طلبی از او داشته باشی، آن را بر من محسوب دار."},{"v":19,"t":"من که پولس هستم، به‌دست خود می‌نویسم، خود ادا خواهم کرد، تا به تو نگویم که به‌جان خود نیز مدیون من هستی."},{"v":20,"t":"بلی‌ای برادر، تا من از تو در خداوندبرخوردار شوم. پس جان مرا در مسیح تازگی بده."},{"v":21,"t":"چون بر اطاعت تو اعتماد دارم، به تومی نویسم از آن جهت که می‌دانم بیشتر از آنچه می‌گویم هم خواهی کرد."},{"v":22,"t":"معهذا منزلی نیز برای من حاضر کن، زیراکه امیدوارم از دعاهای شما به شما بخشیده شوم."},{"v":23,"t":"اپفراس که در مسیح عیسی همزندان من است و مرقس"},{"v":24,"t":"و ارسترخس و دیماس و لوقاهمکاران من تو را سلام می‌رسانند."},{"v":25,"t":"فیض خداوند عیسی مسیح با روح شما باد. آمین."}],"en":[{"v":1,"t":"Paul, a prisoner of Christ Jesus, and Timothy our brother, to Philemon, our beloved fellow worker,"},{"v":2,"t":"to the beloved Apphia, to Archippus our fellow soldier, and to the assembly in your house:"},{"v":3,"t":"Grace to you and peace from God our Father and the Lord Jesus Christ."},{"v":4,"t":"I thank my God always, making mention of you in my prayers,"},{"v":5,"t":"hearing of your love and of the faith which you have toward the Lord Jesus and toward all the saints,"},{"v":6,"t":"that the fellowship of your faith may become effective in the knowledge of every good thing which is in us in Christ Jesus."},{"v":7,"t":"For we have much joy and comfort in your love, because the hearts of the saints have been refreshed through you, brother."},{"v":8,"t":"Therefore though I have all boldness in Christ to command you that which is appropriate,"},{"v":9,"t":"yet for love’s sake I rather appeal to you, being such a one as Paul, the aged, but also a prisoner of Jesus Christ."},{"v":10,"t":"I appeal to you for my child Onesimus, whom I have become the father of in my chains,"},{"v":11,"t":"who once was useless to you, but now is useful to you and to me."},{"v":12,"t":"I am sending him back. Therefore receive him, that is, my own heart,"},{"v":13,"t":"whom I desired to keep with me, that on your behalf he might serve me in my chains for the Good News."},{"v":14,"t":"But I was willing to do nothing without your consent, that your goodness would not be as of necessity, but of free will."},{"v":15,"t":"For perhaps he was therefore separated from you for a while that you would have him forever,"},{"v":16,"t":"no longer as a slave, but more than a slave, a beloved brother—especially to me, but how much rather to you, both in the flesh and in the Lord."},{"v":17,"t":"If then you count me a partner, receive him as you would receive me."},{"v":18,"t":"But if he has wronged you at all or owes you anything, put that to my account."},{"v":19,"t":"I, Paul, write this with my own hand: I will repay it (not to mention to you that you owe to me even your own self besides)."},{"v":20,"t":"Yes, brother, let me have joy from you in the Lord. Refresh my heart in the Lord."},{"v":21,"t":"Having confidence in your obedience, I write to you, knowing that you will do even beyond what I say."},{"v":22,"t":"Also, prepare a guest room for me, for I hope that through your prayers I will be restored to you."},{"v":23,"t":"Epaphras, my fellow prisoner in Christ Jesus, greets you,"},{"v":24,"t":"as do Mark, Aristarchus, Demas, and Luke, my fellow workers."},{"v":25,"t":"The grace of our Lord Jesus Christ be with your spirit. Amen."}],"hr":[{"v":1,"t":"Pavao, sužanj Isusa Krista, i brat Timotej: ljubljenom Filemonu, suradniku našemu,"},{"v":2,"t":"i sestri Apiji, i Arhipu, suborcu našem, i Crkvi u tvojoj kući."},{"v":3,"t":"Milost vam i mir od Boga, Oca našega, i Gospodina Isusa Krista!"},{"v":4,"t":"Zahvaljujem svagda Bogu svojemu spominjući te se u svojim molitvama"},{"v":5,"t":"jer čujem za tvoju ljubav i vjeru koju imaš prema Gospodinu Isusu Kristu i prema svima svetima."},{"v":6,"t":"Nek zajedništvo tvoje vjere bude djelotvorno u spoznanju svakoga mogućeg dobra među vama poradi Krista!"},{"v":7,"t":"Uvelike si me doista obradovao i utješio svojom ljubavlju jer si, brate, okrijepio srca svetih."},{"v":8,"t":"Stoga, premda imam punu slobodu u Kristu da ti zapovjedim što ti je činiti,"},{"v":9,"t":"poradi ljubavi radije molim, kakav već jesam, Pavao, starac, a sada i sužanj Krista Isusa."},{"v":10,"t":"Molim te za svoje dijete koje rodih u okovima, za Onezima,"},{"v":11,"t":"negda tebi nekorisna, a sada i tebi i meni veoma korisna."},{"v":12,"t":"Šaljem ti ga - njega, srce svoje."},{"v":13,"t":"Htjedoh ga zadržati kod sebe da mi mjesto tebe posluži u okovima evanđelja."},{"v":14,"t":"Ali ne htjedoh preko tvoje volje da ne bi tvoja dobrota bila od nevolje, nego od dobre volje."},{"v":15,"t":"Možda baš zato bi za čas odijeljen da ga dobiješ zauvijek -"},{"v":16,"t":"ne kao roba, nego više od roba, kao brata ljubljenoga, osobito meni, a koliko više tebi, i po tijelu i po Gospodinu."},{"v":17,"t":"Smatraš li me dakle drugom, primi ga kao mene."},{"v":18,"t":"Ako ti je u čemu skrivio ili ti je što dužan, to meni upiši."},{"v":19,"t":"Ja, Pavao, potpisujem svojom rukom: ja ću platiti. Da ti ne reknem da mi i samoga sebe duguješ!"},{"v":20,"t":"Hajde, brate, da se tobom okoristim u Gospodinu: okrijepi srce moje u Kristu!"},{"v":21,"t":"Uzdajući se u tvoju poslušnost, napisah ti uvjeren da ćeš još više učiniti, nego te molim."},{"v":22,"t":"K tome, pripravi mi obitavalište jer se nadam da ću vam po vašim molitvama biti darovan."},{"v":23,"t":"Pozdravlja te Epafra, moj suuznik u Kristu Isusu,"},{"v":24,"t":"Marko, Aristarh, Dema i Luka, moji suradnici."},{"v":25,"t":"Milost Gospodina našega Isusa Krista s duhom vašim!"}]}},"HEB":{"1":{"fa":[{"v":1,"t":"خدا که در زمان سلف به اقسام متعدد و طریق های مختلف بوساطت انبیا به پدران ما تکلم نمود،"},{"v":2,"t":"در این ایام آخر به ما بوساطت پسر خود متکلم شد که او را وارث جمیع موجودات قرار داد و بوسیله او عالمها راآفرید؛"},{"v":3,"t":"که فروغ جلالش و خاتم جوهرش بوده و به کلمه قوت خود حامل همه موجودات بوده، چون طهارت گناهان را به اتمام رسانید، به‌دست راست کبریا در اعلی علیین بنشست،"},{"v":4,"t":"و از فرشتگان افضال گردید، بمقدارآنکه اسمی بزرگتر از ایشان به میراث یافته بود."},{"v":5,"t":"زیرا به کدام‌یک از فرشتگان هرگز گفت که «تو پسر من هستی. من امروز تو را تولید نمودم» وایض «من او را پدر خواهم بود و او پسر من خواهدبود»؟"},{"v":6,"t":"و هنگامی که نخست زاده را باز به جهان می‌آورد می‌گوید که «جمیع فرشتگان خدا او راپرستش کنند.»"},{"v":7,"t":"و در حق فرشتگان می‌گوید که «فرشتگان خود را بادها می‌گرداند و خادمان خودرا شعله آتش.»"},{"v":8,"t":"اما در حق پسر: «ای خدا تخت تو تا ابدالاباد است و عصای ملکوت تو عصای راستی است."},{"v":9,"t":"عدالت را دوست و شرارت رادشمن می‌داری. بنابراین خدا، خدای تو، تو را به روغن شادمانی بیشتر از رفقایت مسح کرده است.»"},{"v":10,"t":"و (نیز می‌گوید: ) «تو‌ای خداوند، درابتدا زمین را بنا کردی و افلاک مصنوع دستهای تواست."},{"v":11,"t":"آنها فانی، لکن تو باقی هستی و جمیع آنها چون جامه، مندرس خواهد شد،"},{"v":12,"t":"و مثل ردا آنها را خواهی پیچید و تغییر خواهند یافت. لکن تو همان هستی و سالهای تو تمام نخواهدشد.»"},{"v":13,"t":"و به کدام‌یک از فرشتگان هرگز گفت: «بنشین به‌دست راست من تا دشمنان تو راپای انداز تو سازم»؟"},{"v":14,"t":"آیا همگی ایشان روح های خدمتگذار نیستند که برای خدمت آنانی که وارث نجات خواهند شد، فرستاده می‌شوند؟"}],"en":[{"v":1,"t":"God, having in the past spoken to the fathers through the prophets at many times and in various ways,"},{"v":2,"t":"has at the end of these days spoken to us by his Son, whom he appointed heir of all things, through whom also he made the worlds."},{"v":3,"t":"His Son is the radiance of his glory, the very image of his substance, and upholding all things by the word of his power, who, when he had by himself purified us of our sins, sat down on the right hand of the Majesty on high,"},{"v":4,"t":"having become as much better than the angels as the more excellent name he has inherited is better than theirs."},{"v":5,"t":"For to which of the angels did he say at any time, “You are my Son. Today I have become your father?” and again, “I will be to him a Father, and he will be to me a Son?”"},{"v":6,"t":"When he again brings in the firstborn into the world he says, “Let all the angels of God worship him.”"},{"v":7,"t":"Of the angels he says, “He makes his angels winds, and his servants a flame of fire.”"},{"v":8,"t":"But of the Son he says, “Your throne, O God, is forever and ever. The scepter of uprightness is the scepter of your Kingdom."},{"v":9,"t":"You have loved righteousness and hated iniquity; therefore God, your God, has anointed you with the oil of gladness above your fellows.”"},{"v":10,"t":"And, “You, Lord, in the beginning, laid the foundation of the earth. The heavens are the works of your hands."},{"v":11,"t":"They will perish, but you continue. They all will grow old like a garment does."},{"v":12,"t":"You will roll them up like a mantle, and they will be changed; but you are the same. Your years won’t fail.”"},{"v":13,"t":"But which of the angels has he told at any time, “Sit at my right hand, until I make your enemies the footstool of your feet?”"},{"v":14,"t":"Aren’t they all serving spirits, sent out to do service for the sake of those who will inherit salvation?"}],"hr":[{"v":1,"t":"Više puta i na više načina Bog nekoć govoraše ocima po prorocima;"},{"v":2,"t":"konačno, u ove dane, progovori nama u Sinu. Njega postavi baštinikom svega; Njega po kome sazda svjetove."},{"v":3,"t":"On, koji je odsjaj Slave i otisak Bića njegova te sve nosi snagom riječi svoje, pošto očisti grijehe, sjede zdesna Veličanstvu u visinama;"},{"v":4,"t":"postade toliko moćniji od anđela koliko je uzvišenije nego oni baštinio ime."},{"v":5,"t":"Ta kome od anđela ikad reče: Ti si sin moj, danas te rodih; ili pak: Ja ću njemu biti otac, a on će meni biti sin."},{"v":6,"t":"A opet, kad uvodi Prvorođenca u svijet, govori: Nek pred njim nice padnu svi anđeli Božji."},{"v":7,"t":"Za anđele veli: Anđele čini vjetrovima, sluge svoje plamenom ognjenim,"},{"v":8,"t":"ali za Sina: Prijestolje je tvoje, Bože, u vijeke vjekova, i pravedno žezlo - žezlo je tvog kraljevstva."},{"v":9,"t":"Ti ljubiš pravednost, a mrziš bezakonje, stoga Bog, Bog tvoj, tebe pomaza uljem radosti kao nikog od tvojih drugova."},{"v":10,"t":"I: Ti u početku, Gospodine, utemelji zemlju i nebo je djelo ruku tvojih."},{"v":11,"t":"Propast će, ti ćeš ostati, sve će ostarjeti kao odjeća."},{"v":12,"t":"Mijenjaš ih poput haljine, kao odjeću, i nestaju. A ti si uvijek isti - godinama tvojim nema kraja."},{"v":13,"t":"Za koga pak od anđela ikad reče: Sjedi mi zdesna dok ne položim neprijatelje tvoje za podnožje nogama tvojim!"},{"v":14,"t":"Svi ti zar nisu služnički duhovi što se šalju služiti za one koji imaju baštiniti spasenje?"}]},"2":{"fa":[{"v":1,"t":"لهذا لازم است که به دقت بلیغ تر آنچه راشنیدیم گوش دهیم، مبادا که از آن ربوده شویم."},{"v":2,"t":"زیرا هر گاه کلامی که بوساطت فرشتگان گفته شد برقرار گردید، بقسمی که هر تجاوز وتغافلی را جزای عادل می‌رسید،"},{"v":3,"t":"پس ما چگونه رستگار گردیم اگر از چنین نجاتی عظیم غافل باشیم؟ که در ابتدا تکلم به آن از خداوند بود و بعدکسانی که شنیدند، بر ما ثابت گردانیدند؛"},{"v":4,"t":"درحالتی که خدا نیز با ایشان شهادت می‌داد به آیات و معجزات و انواع قوات و عطایای روح‌القدس برحسب اراده خود."},{"v":5,"t":"زیرا عالم آینده‌ای را که ذکر آن را می‌کنیم مطیع فرشتگان نساخت."},{"v":6,"t":"لکن کسی در موضعی شهادت داده، گفت: «چیست انسان که او را بخاطرآوری یا پسر انسان که از او تفقد نمایی؟"},{"v":7,"t":"او را ازفرشتگان اندکی پست‌تر قرار دادی و تاج جلال واکرام را بر سر او نهادی و او را بر اعمال دستهای خود گماشتی."},{"v":8,"t":"همه‌چیز را زیر پایهای اونهادی.» پس چون همه‌چیز را مطیع او گردانید، هیچ‌چیز را نگذاشت که مطیع او نباشد. لکن الان هنوز نمی بینیم که همه‌چیز مطیع وی شده باشد."},{"v":9,"t":"اما او را که اندکی از فرشتگان کمتر شد می‌بینیم، یعنی عیسی را که به زحمت موت تاج جلال واکرام بر سر وی نهاده شد تا به فیض خدا برای همه ذائقه موت را بچشد."},{"v":10,"t":"زیرا او را که بخاطروی همه و از وی همه‌چیز می‌باشد، چون فرزندان بسیار را وارد جلال می‌گرداند، شایسته بود که رئیس نجات ایشان را به دردها کامل گرداند."},{"v":11,"t":"زانرو که چون مقدس کننده و مقدسان همه از یک می‌باشند، از این جهت عار ندارد که ایشان را برادر بخواند."},{"v":12,"t":"چنانکه می‌گوید: «اسم تو را به برادران خود اعلام می‌کنم و در میان کلیساتو را تسبیح خواهم خواند.»"},{"v":13,"t":"و ایض: «من بروی توکل خواهم نمود.» و نیز: «اینک من وفرزندانی که خدا به من عطا فرمود.»"},{"v":14,"t":"پس چون فرزندان در خون و جسم شراکت دارند، او نیز همچنان در این هر دو شریک شد تابوساطت موت، صاحب قدرت موت یعنی ابلیس را تباه سازد،"},{"v":15,"t":"و آنانی را که از ترس موت، تمام عمر خود را گرفتار بندگی می‌بودند، آزاد گرداند."},{"v":16,"t":"زیرا که در حقیقت فرشتگان را دستگیری نمی نماید بلکه نسل ابراهیم را دستگیری می‌نماید."},{"v":17,"t":"از این جهت می‌بایست در هر امری مشابه برادران خود شود تا در امور خدا رئیس کهنه‌ای کریم و امین شده، کفاره گناهان قوم رابکند."},{"v":18,"t":"زیرا که چون خود عذاب کشیده، تجربه دید استطاعت دارد که تجربه شدگان را اعانت فرماید."}],"en":[{"v":1,"t":"Therefore we ought to pay greater attention to the things that were heard, lest perhaps we drift away."},{"v":2,"t":"For if the word spoken through angels proved steadfast, and every transgression and disobedience received a just penalty,"},{"v":3,"t":"how will we escape if we neglect so great a salvation—which at the first having been spoken through the Lord, was confirmed to us by those who heard,"},{"v":4,"t":"God also testifying with them, both by signs and wonders, by various works of power, and by gifts of the Holy Spirit, according to his own will?"},{"v":5,"t":"For he didn’t subject the world to come, of which we speak, to angels."},{"v":6,"t":"But one has somewhere testified, saying, “What is man, that you think of him? Or the son of man, that you care for him?"},{"v":7,"t":"You made him a little lower than the angels. You crowned him with glory and honor."},{"v":8,"t":"You have put all things in subjection under his feet.” For in that he subjected all things to him, he left nothing that is not subject to him. But now we don’t yet see all things subjected to him."},{"v":9,"t":"But we see him who has been made a little lower than the angels, Jesus, because of the suffering of death crowned with glory and honor, that by the grace of God he should taste of death for everyone."},{"v":10,"t":"For it became him, for whom are all things and through whom are all things, in bringing many children to glory, to make the author of their salvation perfect through sufferings."},{"v":11,"t":"For both he who sanctifies and those who are sanctified are all from one, for which cause he is not ashamed to call them brothers,"},{"v":12,"t":"saying, “I will declare your name to my brothers. Among the congregation I will sing your praise.”"},{"v":13,"t":"Again, “I will put my trust in him.” Again, “Behold, here I am with the children whom God has given me.”"},{"v":14,"t":"Since then the children have shared in flesh and blood, he also himself in the same way partook of the same, that through death he might bring to nothing him who had the power of death, that is, the devil,"},{"v":15,"t":"and might deliver all of them who through fear of death were all their lifetime subject to bondage."},{"v":16,"t":"For most certainly, he doesn’t give help to angels, but he gives help to the offspring of Abraham."},{"v":17,"t":"Therefore he was obligated in all things to be made like his brothers, that he might become a merciful and faithful high priest in things pertaining to God, to make atonement for the sins of the people."},{"v":18,"t":"For in that he himself has suffered being tempted, he is able to help those who are tempted."}],"hr":[{"v":1,"t":"Zato treba da mi svesrdnije prianjamo uz ono što čusmo da ne bismo promašili."},{"v":2,"t":"Jer ako je riječ po anđelima izrečena bila čvrsta te je svaki prijestup i neposluh primio pravednu plaću,"},{"v":3,"t":"kako li ćemo mi umaći ako zanemarimo toliko spasenje? Spasenje koje je počeo propovijedati Gospodin, koje su nam potvrdili slušatelji,"},{"v":4,"t":"a suposvjedočio Bog znamenjima i čudesima, najrazličitijim silnim djelima i darivanjima Duha Svetoga po svojoj volji."},{"v":5,"t":"Nije doista anđelima podložio budući svijet o kojem govorimo."},{"v":6,"t":"Netko negdje posvjedoči: Što je čovjek da ga se spominješ, sin čovječji te ga pohađaš."},{"v":7,"t":"Ti ga tek za malo učini manjim od anđela, slavom i časti njega ovjenča,"},{"v":8,"t":"njemu pod noge sve podloži. Kad mu, doista, sve podloži, ništa ne ostavi što mu ne bi bilo podloženo. Sad još ne vidimo da mu je sve podloženo,"},{"v":9,"t":"ali Njega, za malo manjeg od anđela, Isusa, vidimo zbog pretrpljene smrti slavom i časti ovjenčana da milošću Božjom bude svakome na korist što je on smrt okusio."},{"v":10,"t":"Dolikovalo je doista da Onaj radi kojega je sve i po kojemu je sve - kako bi mnoge sinove priveo k slavi - po patnjama do savršenstva dovede Početnika njihova spasenja."},{"v":11,"t":"Ta i Posvetitelj i posvećeni - svi su od jednoga! Zato se on i ne stidi zvati ih braćom,"},{"v":12,"t":"kad veli: Braći ću svojoj naviještat ime tvoje, hvalit ću te usred zbora."},{"v":13,"t":"I još: Ja ću se u njega uzdati, i još: Evo, ja i djeca koju mi Bog dade."},{"v":14,"t":"Pa budući da djeca imaju zajedničku krv i meso, i sam on tako postade u tome sudionikom da smrću obeskrijepi onoga koji imaše moć smrti, to jest đavla,"},{"v":15,"t":"pa oslobodi one koji - od straha pred smrću - kroza sav život bijahu podložni ropstvu."},{"v":16,"t":"Ta ne zauzima se dašto za anđele, nego se zauzima za potomstvo Abrahamovo."},{"v":17,"t":"Stoga je trebalo da u svemu postane braći sličan, da milosrdan bude i ovjerovljen Veliki svećenik u odnosu prema Bogu kako bi okajavao grijehe naroda."},{"v":18,"t":"Doista, u čemu je iskušan trpio, može iskušavanima pomoći."}]},"3":{"fa":[{"v":1,"t":"بنابراین، ای برادران مقدس که در دعوت سماوی شریک هستید، در رسول و رئیس کهنه اعتراف ما یعنی عیسی تامل کنید،"},{"v":2,"t":"که نزداو که وی را معین فرمود امین بود، چنانکه موسی نیز در تمام خانه او بود."},{"v":3,"t":"زیرا که این شخص لایق اکرامی بیشتر از موسی شمرده شد به آن اندازه‌ای که سازنده خانه را حرمت بیشتر از خانه است."},{"v":4,"t":"زیرا هر خانه‌ای بدست کسی بنا می‌شود، لکن بانی همه خداست."},{"v":5,"t":"و موسی مثل خادم در تمام خانه او امین بود تا شهادت دهد بر چیزهایی که می‌بایست بعد گفته شود."},{"v":6,"t":"و اما مسیح مثل پسربر خانه او. و خانه او ما هستیم بشرطی که تا به انتهابه دلیری و فخر امید خود متمسک باشیم."},{"v":7,"t":"پس چنانکه روح‌القدس می‌گوید: «امروزاگر آواز او را بشنوید،"},{"v":8,"t":"دل خود را سخت مسازید، چنانکه در وقت جنبش دادن خشم او درروز امتحان در بیابان،"},{"v":9,"t":"جایی که پدران شما مراامتحان و آزمایش کردند و اعمال مرا تا مدت چهل سال می‌دیدند."},{"v":10,"t":"از این جهت به آن گروه خشم گرفته، گفتم ایشان پیوسته در دلهای خودگمراه هستند و راههای مرا نشناختند."},{"v":11,"t":"تا درخشم خود قسم خوردم که به آرامی من داخل نخواهند شد.»"},{"v":12,"t":"‌ای برادران، باحذر باشید مبادا در یکی ازشما دل شریر و بی‌ایمان باشد که از خدای حی مرتد شوید،"},{"v":13,"t":"بلکه هر روزه همدیگر رانصیحت کنید مادامی که «امروز» خوانده می‌شود، مبادا احدی از شما به فریب گناه سخت دل گردد."},{"v":14,"t":"از آنرو که در مسیح شریک گشته‌ایم اگر به ابتدای اعتماد خود تا به انتهاسخت متمسک شویم."},{"v":15,"t":"چونکه گفته می‌شود: «امروز اگر آواز او را بشنوید، دل خود را سخت مسازید، چنانکه در وقت جنبش دادن خشم او.»"},{"v":16,"t":"پس که بودند که شنیدند و خشم او راجنبش دادند؟ آیا تمام آن گروه نبودند که بواسطه موسی از مصر بیرون آمدند؟"},{"v":17,"t":"و به که تا مدت چهل سال خشمگین می‌بود؟ آیا نه به آن عاصیانی که بدنهای ایشان در صحرا ریخته شد؟"},{"v":18,"t":"و درباره که قسم خورد که به آرامی من داخل نخواهند شد، مگر آنانی را که اطاعت نکردند؟"},{"v":19,"t":"پس دانستیم که به‌سبب بی‌ایمانی نتوانستندداخل شوند."}],"en":[{"v":1,"t":"Therefore, holy brothers, partakers of a heavenly calling, consider the Apostle and High Priest of our confession: Jesus,"},{"v":2,"t":"who was faithful to him who appointed him, as also Moses was in all his house."},{"v":3,"t":"For he has been counted worthy of more glory than Moses, because he who built the house has more honor than the house."},{"v":4,"t":"For every house is built by someone; but he who built all things is God."},{"v":5,"t":"Moses indeed was faithful in all his house as a servant, for a testimony of those things which were afterward to be spoken,"},{"v":6,"t":"but Christ is faithful as a Son over his house. We are his house, if we hold fast our confidence and the glorying of our hope firm to the end."},{"v":7,"t":"Therefore, even as the Holy Spirit says, “Today if you will hear his voice,"},{"v":8,"t":"don’t harden your hearts as in the rebellion, in the day of the trial in the wilderness,"},{"v":9,"t":"where your fathers tested me and tried me, and saw my deeds for forty years."},{"v":10,"t":"Therefore I was displeased with that generation, and said, ‘They always err in their heart, but they didn’t know my ways.’"},{"v":11,"t":"As I swore in my wrath, ‘They will not enter into my rest.’”"},{"v":12,"t":"Beware, brothers, lest perhaps there might be in any one of you an evil heart of unbelief, in falling away from the living God;"},{"v":13,"t":"but exhort one another day by day, so long as it is called “today”, lest any one of you be hardened by the deceitfulness of sin."},{"v":14,"t":"For we have become partakers of Christ, if we hold the beginning of our confidence firm to the end,"},{"v":15,"t":"while it is said, “Today if you will hear his voice, don’t harden your hearts, as in the rebellion.”"},{"v":16,"t":"For who, when they heard, rebelled? Wasn’t it all those who came out of Egypt led by Moses?"},{"v":17,"t":"With whom was he displeased forty years? Wasn’t it with those who sinned, whose bodies fell in the wilderness?"},{"v":18,"t":"To whom did he swear that they wouldn’t enter into his rest, but to those who were disobedient?"},{"v":19,"t":"We see that they weren’t able to enter in because of unbelief."}],"hr":[{"v":1,"t":"Stoga, braćo sveta, sudionici nebeskoga poziva, promotrite Apostola i Velikoga svećenika naše vjere - Isusa:"},{"v":2,"t":"on je ovjerovljen kod Onoga koji ga postavi kao ono i Mojsije u svoj kući njegovoj."},{"v":3,"t":"Dostojan je doista toliko veće slave od Mojsija koliko veću čast od kuće ima onaj tko ju je sagradio."},{"v":4,"t":"Jer svaku kuću tkogod gradi, a sve je sagradio Bog."},{"v":5,"t":"Da, i Mojsije bijaše ovjerovljen u svoj kući njegovoj kao služnik da posvjedoči za ono što je imalo biti rečeno,"},{"v":6,"t":"ali Krist - kao Sin, nad kućom njegovom. Njegova smo kuća mi ako sačuvamo smjelost i ponos nade."},{"v":7,"t":"Zato, kao što veli Duh Sveti: Danas ako glas mu čujete,"},{"v":8,"t":"ne budite srca tvrda kao u Pobuni, kao u dan iskušenja u pustinji"},{"v":9,"t":"gdje me kušnjom iskušavahu očevi vaši premda gledahu djela moja"},{"v":10,"t":"četrdeset godina. Zato mi dodija naraštaj onaj pa rekoh: Uvijek su nestalna srca i ne proniču moje putove."},{"v":11,"t":"Tako se zakleh u svom gnjevu: Nikad neće ući u moj počinak!"},{"v":12,"t":"Pazite, braćo, da ne bi u koga od vas srce bilo opako, nevjerno, odmetnulo se od Boga živoga."},{"v":13,"t":"Pače hrabrite jedni druge dan za danom dok još odjekuje ono Danas da ne otvrdne tko od vas zaveden grijehom."},{"v":14,"t":"Doista, sudionici smo Kristovi postali ako, dakako, ono prvo imanje stalnim sačuvamo"},{"v":15,"t":"kad je rečeno: Danas ako glas mu čujete, ne budite srca tvrda kao u Pobuni!"},{"v":16,"t":"Jer, koji su to čuli pa se pobunili? Zar ne svi koji su pod Mojsijem izašli iz Egipta?"},{"v":17,"t":"Koji li mu dodijavahu četrdeset godina? Zar ne oni koji sagriješiše, kojih mrtva tijela popadaše u pustinji?"},{"v":18,"t":"Kojima se zakle da neće ući u njegov počinak, ako li ne nepokornima?"},{"v":19,"t":"I vidimo da ne mogoše ući zbog nevjere."}]},"4":{"fa":[{"v":1,"t":"پس بترسیم مبادا با آنکه وعده دخول درآرامی وی باقی می‌باشد، ظاهر شود که احدی از شما قاصر شده باشد."},{"v":2,"t":"زیرا که به ما نیز به مثال ایشان بشارت داده شد، لکن کلامی که شنیدند بدیشان نفع نبخشید، از اینرو که باشنوندگان به ایمان متحد نشدند."},{"v":3,"t":"زیرا ما که ایمان آوردیم، داخل آن آرامی می‌گردیم، چنانکه گفته است: «در خشم خود قسم خوردم که به آرامی من داخل نخواهند شد.» و حال آنکه اعمال او از آفرینش عالم به اتمام رسیده بود."},{"v":4,"t":"ودر مقامی درباره روز هفتم گفت که «در روز هفتم خدا از جمیع اعمال خود آرامی گرفت.»"},{"v":5,"t":"و بازدر این مقام که «به آرامی من داخل نخواهند شد.»"},{"v":6,"t":"پس چون باقی است که بعضی داخل آن بشوند و آنانی که پیش بشارت یافتند، به‌سبب نافرمانی داخل نشدند،"},{"v":7,"t":"باز روزی معین می‌فرماید چونکه به زبان داود بعد از مدت مدیدی «امروز» گفت، چنانکه پیش مذکور شدکه «امروز اگر آواز او را بشنوید، دل خود راسخت مسازید.»"},{"v":8,"t":"زیرا اگر یوشع ایشان را آرامی داده بود، بعد از آن دیگر را ذکر نمی کرد."},{"v":9,"t":"پس برای قوم خدا آرامی سبت باقی می‌ماند."},{"v":10,"t":"زیراهر‌که داخل آرامی او شد، او نیز از اعمال خودبیارامید، چنانکه خدا از اعمال خویش."},{"v":11,"t":"پس جد و جهد بکنیم تا به آن آرامی داخل شویم، مبادا کسی در آن نافرمانی عبرت آمیز بیفتد."},{"v":12,"t":"زیرا کلام خدا زنده و مقتدر و برنده تر است ازهر شمشیر دودم و فرورونده تا جدا کند نفس وروح و مفاصل و مغز را و ممیز افکار و نیتهای قلب است،"},{"v":13,"t":"و هیچ خلقت از نظر او مخفی نیست بلکه همه‌چیز در چشمان او که کار ما باوی است، برهنه و منکشف می‌باشد."},{"v":14,"t":"پس چون رئیس کهنه عظیمی داریم که ازآسمانها درگذشته است یعنی عیسی، پسر خدا، اعتراف خود را محکم بداریم."},{"v":15,"t":"زیرا رئیس کهنه‌ای نداریم که نتواند همدرد ضعفهای مابشود، بلکه آزموده شده در هر چیز به مثال مابدون گناه."},{"v":16,"t":"پس با دلیری نزدیک به تخت فیض بیاییم تا رحمت بیابیم و فیضی را حاصل کنیم که در وقت ضرورت (ما را) اعانت کند."}],"en":[{"v":1,"t":"Let’s fear therefore, lest perhaps anyone of you should seem to have come short of a promise of entering into his rest."},{"v":2,"t":"For indeed we have had good news preached to us, even as they also did, but the word they heard didn’t profit them, because it wasn’t mixed with faith by those who heard."},{"v":3,"t":"For we who have believed do enter into that rest, even as he has said, “As I swore in my wrath, they will not enter into my rest;” although the works were finished from the foundation of the world."},{"v":4,"t":"For he has said this somewhere about the seventh day, “God rested on the seventh day from all his works;”"},{"v":5,"t":"and in this place again, “They will not enter into my rest.”"},{"v":6,"t":"Seeing therefore it remains that some should enter into it, and they to whom the good news was preached before failed to enter in because of disobedience,"},{"v":7,"t":"he again defines a certain day, “today”, saying through David so long a time afterward (just as has been said), “Today if you will hear his voice, don’t harden your hearts.”"},{"v":8,"t":"For if Joshua had given them rest, he would not have spoken afterward of another day."},{"v":9,"t":"There remains therefore a Sabbath rest for the people of God."},{"v":10,"t":"For he who has entered into his rest has himself also rested from his works, as God did from his."},{"v":11,"t":"Let’s therefore give diligence to enter into that rest, lest anyone fall after the same example of disobedience."},{"v":12,"t":"For the word of God is living and active, and sharper than any two-edged sword, piercing even to the dividing of soul and spirit, of both joints and marrow, and is able to discern the thoughts and intentions of the heart."},{"v":13,"t":"There is no creature that is hidden from his sight, but all things are naked and laid open before the eyes of him to whom we must give an account."},{"v":14,"t":"Having then a great high priest who has passed through the heavens, Jesus, the Son of God, let’s hold tightly to our confession."},{"v":15,"t":"For we don’t have a high priest who can’t be touched with the feeling of our infirmities, but one who has been in all points tempted like we are, yet without sin."},{"v":16,"t":"Let’s therefore draw near with boldness to the throne of grace, that we may receive mercy and may find grace for help in time of need."}],"hr":[{"v":1,"t":"Bojmo se dakle da se, dok ostaje obećanje o ulasku u njegov Počinak, za koga od vas ne bi utvrdilo kako je zakasnio."},{"v":2,"t":"Jer nama je naviještena blagovijest kao i njima, ali njima Riječ poruke nije uskoristila jer se vjerom nisu pridružili onima koji su poslušali."},{"v":3,"t":"U Počinak doista ulazimo mi koji povjerovasmo, prema onom što je rekao: Tako se zakleh u svom gnjevu: Nikad neće ući u moj počinak, premda su djela od postanka svijeta dovršena."},{"v":4,"t":"Rekao je doista negdje o sedmom danu ovako: I počinu Bog sedmoga dana od svih djela svojih."},{"v":5,"t":"A ovdje opet: Nikad neće ući u moj počinak."},{"v":6,"t":"Preostaje dakle da neki imaju u nj ući, a oni koji su prvi primili blagovijest ne uđoše zbog nepokornosti."},{"v":7,"t":"Zato Bog ponovno određuje jedan dan, Danas, u Davidu nakon toliko vremena govoreći, kako je već rečeno: Danas ako glas mu čujete, ne budite srca tvrda."},{"v":8,"t":"Zbilja, da je Jošua njih u Počinak uveo, ne bi Bog nakon toga govorio o drugome danu."},{"v":9,"t":"Dakle: preostaje neki subotni počinak narodu Božjemu!"},{"v":10,"t":"Zaista, tko uđe u njegov počinak, počinuo je od djela svojih kao ono i Bog od svojih."},{"v":11,"t":"Pohitimo dakle ući u taj Počinak da nitko ne padne po uzoru na takvu nepokornost."},{"v":12,"t":"Živa je, uistinu, Riječ Božja i djelotvorna; oštrija je od svakoga dvosjekla mača; prodire dotle da dijeli dušu i duh, zglobove i moždinu te prosuđuje nakane i misli srca."},{"v":13,"t":"Nema stvorenja njoj skrivena. Sve je, naprotiv, golo i razgoljeno očima Onoga komu nam je dati račun."},{"v":14,"t":"Imajući dakle velikoga Velikog svećenika koji prodrije kroz nebesa - Isusa, Sina Božjega - čvrsto se držimo vjere."},{"v":15,"t":"Ta nemamo takva Velikog svećenika koji ne bi mogao biti supatnik u našim slabostima, nego poput nas iskušavana svime, osim grijehom."},{"v":16,"t":"Pristupajmo dakle smjelo Prijestolju milosti da primimo milosrđe i milost nađemo za pomoć u pravi čas!"}]},"5":{"fa":[{"v":1,"t":"زیرا که هر رئیس کهنه از میان آدمیان گرفته شده، برای آدمیان مقرر می‌شود در امورالهی تا هدایا و قربانی‌ها برای گناهان بگذراند؛"},{"v":2,"t":"که با جاهلان و گمراهان می‌تواند ملایمت کند، چونکه او نیز در کمزوری گرفته شده است."},{"v":3,"t":"و به‌سبب این کمزوری، او را لازم است چنانکه برای قوم، همچنین برای خویشتن نیز قربانی برای گناهان بگذراند."},{"v":4,"t":"و کسی این مرتبه را برای خودنمی گیرد، مگر وقتی که خدا او را بخواند، چنانکه هارون را."},{"v":5,"t":"و همچنین مسیح نیز خود را جلال نداد که رئیس کهنه بشود، بلکه او که به وی گفت: «تو پسر من هستی؛ من امروز تو را تولید نمودم.»"},{"v":6,"t":"چنانکه در مقام دیگر نیز می‌گوید: «تو تا به ابدکاهن هستی بر رتبه ملکیصدق.»"},{"v":7,"t":"و او در ایام بشریت خود، چونکه با فریادشدید و اشکها نزد او که به رهانیدنش از موت قادر بود، تضرع و دعای بسیار کرد و به‌سبب تقوای خویش مستجاب گردید،"},{"v":8,"t":"هر‌چند پسربود، به مصیبتهایی که کشید، اطاعت را آموخت"},{"v":9,"t":"و کامل شده، جمیع مطیعان خود را سبب نجات جاودانی گشت."},{"v":10,"t":"و خدا او را به رئیس کهنه مخاطب ساخت به رتبه ملکیصدق."},{"v":11,"t":"که درباره او ما را سخنان بسیار است که شرح آنها مشکل می‌باشد چونکه گوشهای شماسنگین شده است."},{"v":12,"t":"زیرا که هر‌چند با این طول زمان شما را می‌باید معلمان باشید، باز محتاجیدکه کسی اصول و مبادی الهامات خدا را به شمابیاموزد و محتاج شیر شدید نه غذای قوی."},{"v":13,"t":"زیرا هر‌که شیرخواره باشد، در کلام عدالت ناآزموده است، چونکه طفل است."},{"v":14,"t":"اما غذای قوی از آن بالغان است که حواس خود را به موجب عادت، ریاضت داده‌اند تا تمییز نیک و بدرا بکنند."}],"en":[{"v":1,"t":"For every high priest, being taken from among men, is appointed for men in things pertaining to God, that he may offer both gifts and sacrifices for sins."},{"v":2,"t":"The high priest can deal gently with those who are ignorant and going astray, because he himself is also surrounded with weakness."},{"v":3,"t":"Because of this, he must offer sacrifices for sins for the people, as well as for himself."},{"v":4,"t":"Nobody takes this honor on himself, but he is called by God, just like Aaron was."},{"v":5,"t":"So also Christ didn’t glorify himself to be made a high priest, but it was he who said to him, “You are my Son. Today I have become your father.”"},{"v":6,"t":"As he says also in another place, “You are a priest forever, after the order of Melchizedek.”"},{"v":7,"t":"He, in the days of his flesh, having offered up prayers and petitions with strong crying and tears to him who was able to save him from death, and having been heard for his godly fear,"},{"v":8,"t":"though he was a Son, yet learned obedience by the things which he suffered."},{"v":9,"t":"Having been made perfect, he became to all of those who obey him the author of eternal salvation,"},{"v":10,"t":"named by God a high priest after the order of Melchizedek."},{"v":11,"t":"About him we have many words to say, and hard to interpret, seeing you have become dull of hearing."},{"v":12,"t":"For although by this time you should be teachers, you again need to have someone teach you the rudiments of the first principles of the revelations of God. You have come to need milk, and not solid food."},{"v":13,"t":"For everyone who lives on milk is not experienced in the word of righteousness, for he is a baby."},{"v":14,"t":"But solid food is for those who are full grown, who by reason of use have their senses exercised to discern good and evil."}],"hr":[{"v":1,"t":"Svaki veliki svećenik, zaista, od ljudi uzet, za ljude se postavlja u odnosu prema Bogu da prinosi darove i žrtve za grijehe."},{"v":2,"t":"On može primjereno suosjećati s onima koji su u neznanju i zabludi jer je i sam zaogrnut slabošću."},{"v":3,"t":"Zato mora i za narod i za sebe prinositi okajnice."},{"v":4,"t":"I nitko sam sebi ne prisvaja tu čast, nego je prima od Boga, pozvan kao Aron."},{"v":5,"t":"Tako i Krist ne proslavi sam sebe postavši svećenik, nego ga proslavi Onaj koji mu reče: Ti si sin moj, danas te rodih,"},{"v":6,"t":"po onome što pak drugdje veli: Zauvijek ti si svećenik po redu Melkisedekovu."},{"v":7,"t":"On je u dane svoga zemaljskog života sa silnim vapajem i suzama prikazivao molitve i prošnje Onomu koji ga je mogao spasiti od smrti. I bi uslišan zbog svoje predanosti:"},{"v":8,"t":"premda je Sin, iz onoga što prepati, naviknu slušati"},{"v":9,"t":"i, postigavši savršenstvo, posta svima koji ga slušaju začetnik vječnoga spasenja -"},{"v":10,"t":"proglašen od Boga Velikim svećenikom po redu Melkisedekovu."},{"v":11,"t":"O tome nas čeka besjeda velika, ali teško ju je riječima izložiti jer ste tvrdih ušiju."},{"v":12,"t":"Pa trebalo bi doista da nakon toliko vremena već budete učitelji, a ono treba da tkogod vas ponovno poučava početnička počela kazivanja Božjih. Takvi ste: mlijeka vam treba, a ne tvrde hrane."},{"v":13,"t":"Doista, tko je god još pri mlijeku, ne zna ništa o nauku pravednosti jer - nejače je."},{"v":14,"t":"A za zrele je tvrda hrana, za one koji imaju iskustvom izvježbana čula za rasuđivanje dobra i zla."}]},"6":{"fa":[{"v":1,"t":"بنابراین، از کلام ابتدای مسیح درگذشته، به سوی کمال سبقت بجوییم و بار دیگر بنیادتوبه از اعمال مرده و ایمان به خدا ننهیم،"},{"v":2,"t":"وتعلیم تعمیدها و نهادن دستها و قیامت مردگان وداوری جاودانی را."},{"v":3,"t":"و این را به‌جا خواهیم آوردهر گاه خدا اجازت دهد."},{"v":4,"t":"زیرا آنانی که یک بار منور گشتند و لذت عطای سماوی را چشیدند و شریک روح‌القدس گردیدند"},{"v":5,"t":"و لذت کلام نیکوی خدا و قوات عالم آینده را چشیدند،"},{"v":6,"t":"اگر بیفتند، محال است که ایشان را بار دیگر برای توبه تازه سازند، در حالتی که پسر خدا را برای خود باز مصلوب می‌کنند واو را بی‌حرمت می‌سازند."},{"v":7,"t":"زیرا زمینی که بارانی را که بارها بر آن می‌افتد، می‌خورد و نباتات نیکو برای فلاحان خود می‌رویاند، از خدا برکت می‌یابد."},{"v":8,"t":"لکن اگر خار و خسک می‌رویاند، متروک و قرین به لعنت و در آخر، سوخته می‌شود."},{"v":9,"t":"اما‌ای عزیزان در حق شما چیزهای بهتر وقرین نجات را یقین می‌داریم، هر‌چند بدینطورسخن می‌گوییم."},{"v":10,"t":"زیرا خدا بی‌انصاف نیست که عمل شما و آن محبت را که به اسم او از خدمت مقدسین که در آن مشغول بوده و هستید ظاهرکرده‌اید، فراموش کند."},{"v":11,"t":"لکن آرزوی این داریم که هر یک از شما همین جد و جهد را برای یقین کامل امید تا به انتها ظاهر نمایید،"},{"v":12,"t":"و کاهل مشوید بلکه اقتدا کنید آنانی را که به ایمان و صبروارث وعده‌ها می‌باشند."},{"v":13,"t":"زیرا وقتی که خدا به ابراهیم وعده داد، چون به بزرگتر از خود قسم نتوانست خورد، به خود قسم خورده، گفت:"},{"v":14,"t":"«هرآینه من تو رابرکت عظیمی خواهم داد و تو را بی‌نهایت کثیرخواهم گردانید.»"},{"v":15,"t":"و همچنین چون صبر کرد، آن وعده را یافت."},{"v":16,"t":"زیرا مردم به آنکه بزرگتراست، قسم می‌خورند و نهایت هر مخاصمه ایشان قسم است تا اثبات شود."},{"v":17,"t":"از اینرو، چون خدا خواست که عدم تغییر اراده خود را به وارثان وعده به تاکید بی‌شمار ظاهر سازد، قسم در میان آورد."},{"v":18,"t":"تا به دو امر بی‌تغییر که ممکن نیست خدادر مورد آنها دروغ گوید، تسلی قوی حاصل شود برای ما که پناه بردیم تا به آن امیدی که در پیش ما گذارده شده است تمسک جوییم،"},{"v":19,"t":"وآن را مثل لنگری برای جان خود ثابت و پایدارداریم که در درون حجاب داخل شده است،"},{"v":20,"t":"جایی که آن پیشرو برای ما داخل شد یعنی عیسی که بر رتبه ملکیصدق، رئیس کهنه گردید تاابدالاباد."}],"en":[{"v":1,"t":"Therefore leaving the teaching of the first principles of Christ, let’s press on to perfection—not laying again a foundation of repentance from dead works, of faith toward God,"},{"v":2,"t":"of the teaching of baptisms, of laying on of hands, of resurrection of the dead, and of eternal judgment."},{"v":3,"t":"This will we do, if God permits."},{"v":4,"t":"For concerning those who were once enlightened and tasted of the heavenly gift, and were made partakers of the Holy Spirit,"},{"v":5,"t":"and tasted the good word of God and the powers of the age to come,"},{"v":6,"t":"and then fell away, it is impossible to renew them again to repentance; seeing they crucify the Son of God for themselves again, and put him to open shame."},{"v":7,"t":"For the land which has drunk the rain that comes often on it and produces a crop suitable for them for whose sake it is also tilled, receives blessing from God;"},{"v":8,"t":"but if it bears thorns and thistles, it is rejected and near being cursed, whose end is to be burned."},{"v":9,"t":"But, beloved, we are persuaded of better things for you, and things that accompany salvation, even though we speak like this."},{"v":10,"t":"For God is not unrighteous, so as to forget your work and the labor of love which you showed toward his name, in that you served the saints, and still do serve them."},{"v":11,"t":"We desire that each one of you may show the same diligence to the fullness of hope even to the end,"},{"v":12,"t":"that you won’t be sluggish, but imitators of those who through faith and perseverance inherited the promises."},{"v":13,"t":"For when God made a promise to Abraham, since he could swear by no one greater, he swore by himself,"},{"v":14,"t":"saying, “Surely blessing I will bless you, and multiplying I will multiply you.”"},{"v":15,"t":"Thus, having patiently endured, he obtained the promise."},{"v":16,"t":"For men indeed swear by a greater one, and in every dispute of theirs the oath is final for confirmation."},{"v":17,"t":"In this way God, being determined to show more abundantly to the heirs of the promise the immutability of his counsel, interposed with an oath,"},{"v":18,"t":"that by two immutable things, in which it is impossible for God to lie, we may have a strong encouragement, who have fled for refuge to take hold of the hope set before us."},{"v":19,"t":"This hope we have as an anchor of the soul, a hope both sure and steadfast and entering into that which is within the veil,"},{"v":20,"t":"where as a forerunner Jesus entered for us, having become a high priest forever after the order of Melchizedek."}],"hr":[{"v":1,"t":"Stoga mimoiđimo početnički nauk o Kristu i uzdignimo se k savršenome ne postavljajući iznovice temelja: obraćenje od mrtvih djela i vjera u Boga,"},{"v":2,"t":"naučavanje o krštenjima i polaganje ruku, uskrsnuće mrtvih i vječni sud."},{"v":3,"t":"To ćemo pak učiniti, dakako, ako Bog da."},{"v":4,"t":"Zaista, onima koji su jednom prosvijetljeni, i okusili dar nebeski, i postali dionici Duha Svetoga,"},{"v":5,"t":"i okusili Lijepu riječ Božju i snage budućega svijeta,"},{"v":6,"t":"pa otpali, nemoguće je opet se obnoviti na obraćenje kad oni sami ponovno razapinju Sina Božjega i ruglu ga izvrgavaju."},{"v":7,"t":"Jer zemlja koja se napije kiše što na nju često pada i rađa raslinjem korisnim onima za koje se i obrađuje, prima blagoslov od Boga;"},{"v":8,"t":"ona pak koja donosi trnje i drač, odbačena je, blizu prokletstvu a svršetak joj je: “U oganj!”"},{"v":9,"t":"A uvjereni smo, ljubljeni, sve ako tako i govorimo, da je s vama dobro i da ste na putu spasenja."},{"v":10,"t":"Ta Bog nije nepravedan da bi zaboravio vaše djelo i ljubav što je iskazaste njegovu imenu posluživši i poslužujući svetima."},{"v":11,"t":"Želimo ipak da svatko od vas sve do svršetka pokazuje tu istu gorljivost za ispunjenje nade"},{"v":12,"t":"te ne omlitavite, nego budete nasljedovatelji onih koji po vjeri i strpljivosti baštine obećano."},{"v":13,"t":"Doista, kad je Bog Abrahamu davao obećanje, jer se nije imao kime većim zakleti, zakle se samim sobom:"},{"v":14,"t":"Uistinu, blagosloviti, blagoslovit ću te i umnožiti, umnožit ću te."},{"v":15,"t":"I tako Abraham, strpljiv, postiže obećano."},{"v":16,"t":"Ljudi se doista kunu onim tko je veći i zakletva im je, kao potkrepa, kraj svake raspre."},{"v":17,"t":"Tako i Bog: htio je baštinicima obećanja obilatije pokazati nepromjenljivost svoje odluke pa zato zajamči zakletvom"},{"v":18,"t":"da bismo po dva nepromjenljiva čina - u kojima je nemoguće da bi Bog prevario - mi pribjeglice imali snažno ohrabrenje da se držimo ponuđene nade."},{"v":19,"t":"Ona nam je kao pouzdano i čvrsto sidro duše što ulazi u unutrašnjost iza zavjese,"},{"v":20,"t":"kamo je kao preteča za nas ušao Isus postavši zauvijek Veliki svećenik po redu Melkisedekovu."}]},"7":{"fa":[{"v":1,"t":"زیرا این ملکیصدق، پادشاه سالیم و کاهن خدای تعالی، هنگامی که ابراهیم ازشکست دادن ملوک، مراجعت می‌کرد، او رااستقبال کرده، بدو برکت داد."},{"v":2,"t":"و ابراهیم نیز ازهمه‌چیزها ده‌یک بدو داد؛ که او اول ترجمه شده «پادشاه عدالت» است و بعد ملک سالیم نیز یعنی «پادشاه سلامتی»."},{"v":3,"t":"بی‌پدر و بی‌مادر وبی نسب نامه و بدون ابتدای ایام و انتهای حیات بلکه به شبیه پسر خدا شده، کاهن دایمی می‌ماند."},{"v":4,"t":"پس ملاحظه کنید که این شخص چقدربزرگ بود که ابراهیم پاتریارخ نیز از بهترین غنایم، ده‌یک بدو داد."},{"v":5,"t":"و اما از اولاد لاوی کسانی که کهانت را می‌یابند، حکم دارند که از قوم بحسب شریعت ده‌یک بگیرند، یعنی از برادران خود، باآنکه ایشان نیز از صلب ابراهیم پدید آمدند."},{"v":6,"t":"لکن آن کس که نسبتی بدیشان نداشت، ازابراهیم ده‌یک گرفته و صاحب وعده‌ها را برکت داده است."},{"v":7,"t":"و بدون هر شبهه، کوچک از بزرگ برکت داده می‌شود."},{"v":8,"t":"و در اینجا مردمان مردنی ده‌یک می‌گیرند، اما در آنجا کسی‌که بر زنده بودن وی شهادت داده می‌شود."},{"v":9,"t":"حتی آنکه گویا می توان گفت که بوساطت ابراهیم از همان لاوی که ده‌یک می‌گیرد، ده‌یک گرفته شد،"},{"v":10,"t":"زیرا که هنوز در صلب پدر خود بود هنگامی که ملکیصدق او را استقبال کرد."},{"v":11,"t":"و دیگر اگر از کهانت لاوی، کمال حاصل می‌شد (زیرا قوم شریعت را بر آن یافتند)، باز چه احتیاج می‌بود که کاهنی دیگر بر رتبه ملکیصدق مبعوث شود و مذکور شود که بر رتبه هارون نیست؟"},{"v":12,"t":"زیرا هر گاه کهانت تغییر می‌پذیرد، البته شریعت نیز تبدیل می‌یابد."},{"v":13,"t":"زیرا او که این سخنان در حق وی گفته می‌شود، از سبط دیگرظاهر شده است که احدی از آن، خدمت قربانگاه را نکرده است."},{"v":14,"t":"زیرا واضح است که خداوند مااز سبط یهودا طلوع فرمود که موسی در حق آن سبط از جهت کهانت هیچ نگفت."},{"v":15,"t":"و نیز بیشتر مبین است از اینکه به مثال ملکیصدق کاهنی بطور دیگر باید ظهور نماید"},{"v":16,"t":"که به شریعت و احکام جسمی مبعوث نشودبلکه به قوت حیات غیرفانی."},{"v":17,"t":"زیرا شهادت داده شد که «تو تا به ابد کاهن هستی بر رتبه ملکیصدق.»"},{"v":18,"t":"زیرا که حاصل می‌شود هم نسخ حکم سابق بعلت ضعف و عدم فایده آن"},{"v":19,"t":"(از آن جهت که شریعت هیچ‌چیز را کامل نمی گرداند)، و هم برآوردن امید نیکوتر که به آن تقرب به خدامی جوییم."},{"v":20,"t":"و بقدر آنکه این بدون قسم نمی باشد."},{"v":21,"t":"زیرا ایشان بی‌قسم کاهن شده‌اند ولیکن این با قسم از او که به وی می‌گوید: «خداوند قسم خورد و تغییر اراده نخواهد داد که تو کاهن ابدی هستی بر رتبه ملکیصدق.»"},{"v":22,"t":"به همین قدرنیکوتر است آن عهدی که عیسی ضامن آن گردید."},{"v":23,"t":"و ایشان کاهنان بسیار می‌شوند، ازجهت آنکه موت از باقی بودن ایشان مانع است."},{"v":24,"t":"لکن وی چون تا به ابد باقی است، کهانت بی‌زوال دارد."},{"v":25,"t":"از این جهت نیز قادر است که آنانی را که بوسیله وی نزد خدا آیند، نجات بی‌نهایت بخشد، چونکه دائم زنده است تاشفاعت ایشان را بکند."},{"v":26,"t":"زیرا که ما را چنین رئیس کهنه شایسته است، قدوس و بی‌آزار و بی‌عیب و از گناهکاران جدا شده و از آسمانها بلندتر گردیده"},{"v":27,"t":"که هرروز محتاج نباشد به مثال آن روسای کهنه که اول برای گناهان خود و بعد برای قوم قربانی بگذراند، چونکه این را یک بار فقط به‌جا آورد هنگامی که خود را به قربانی گذرانید."},{"v":28,"t":"از آنرو که شریعت مردمانی را که کمزوری دارند کاهن می‌سازد، لکن کلام قسم که بعد از شریعت است، پسر را که تاابدالاباد کامل شده است."}],"en":[{"v":1,"t":"For this Melchizedek, king of Salem, priest of God Most High, who met Abraham returning from the slaughter of the kings and blessed him,"},{"v":2,"t":"to whom also Abraham divided a tenth part of all (being first, by interpretation, “king of righteousness”, and then also “king of Salem”, which means “king of peace”,"},{"v":3,"t":"without father, without mother, without genealogy, having neither beginning of days nor end of life, but made like the Son of God), remains a priest continually."},{"v":4,"t":"Now consider how great this man was, to whom even Abraham the patriarch gave a tenth out of the best plunder."},{"v":5,"t":"They indeed of the sons of Levi who receive the priest’s office have a commandment to take tithes from the people according to the law, that is, of their brothers, though these have come out of the body of Abraham,"},{"v":6,"t":"but he whose genealogy is not counted from them has accepted tithes from Abraham, and has blessed him who has the promises."},{"v":7,"t":"But without any dispute the lesser is blessed by the greater."},{"v":8,"t":"Here people who die receive tithes, but there one receives tithes of whom it is testified that he lives."},{"v":9,"t":"We can say that through Abraham even Levi, who receives tithes, has paid tithes,"},{"v":10,"t":"for he was yet in the body of his father when Melchizedek met him."},{"v":11,"t":"Now if perfection was through the Levitical priesthood (for under it the people have received the law), what further need was there for another priest to arise after the order of Melchizedek, and not be called after the order of Aaron?"},{"v":12,"t":"For the priesthood being changed, there is of necessity a change made also in the law."},{"v":13,"t":"For he of whom these things are said belongs to another tribe, from which no one has officiated at the altar."},{"v":14,"t":"For it is evident that our Lord has sprung out of Judah, about which tribe Moses spoke nothing concerning priesthood."},{"v":15,"t":"This is yet more abundantly evident, if after the likeness of Melchizedek there arises another priest,"},{"v":16,"t":"who has been made, not after the law of a fleshly commandment, but after the power of an endless life;"},{"v":17,"t":"for it is testified, “You are a priest forever, according to the order of Melchizedek.”"},{"v":18,"t":"For there is an annulling of a foregoing commandment because of its weakness and uselessness"},{"v":19,"t":"(for the law made nothing perfect), and a bringing in of a better hope, through which we draw near to God."},{"v":20,"t":"Inasmuch as he was not made priest without the taking of an oath"},{"v":21,"t":"(for they indeed have been made priests without an oath), but he with an oath by him that says of him, “The Lord swore and will not change his mind, ‘You are a priest forever, according to the order of Melchizedek.’”"},{"v":22,"t":"By so much, Jesus has become the guarantee of a better covenant."},{"v":23,"t":"Many, indeed, have been made priests, because they are hindered from continuing by death."},{"v":24,"t":"But he, because he lives forever, has his priesthood unchangeable."},{"v":25,"t":"Therefore he is also able to save to the uttermost those who draw near to God through him, seeing that he lives forever to make intercession for them."},{"v":26,"t":"For such a high priest was fitting for us: holy, guiltless, undefiled, separated from sinners, and made higher than the heavens;"},{"v":27,"t":"who doesn’t need, like those high priests, to offer up sacrifices daily, first for his own sins, and then for the sins of the people. For he did this once for all, when he offered up himself."},{"v":28,"t":"For the law appoints men as high priests who have weakness, but the word of the oath, which came after the law, appoints a Son forever who has been perfected."}],"hr":[{"v":1,"t":"Doista, taj Melkisedek, kralj šalemski, svećenik Boga Svevišnjega što je izašao u susret Abrahamu koji se vraćao s poraza kraljeva i blagoslovio ga,"},{"v":2,"t":"i komu Abraham odijeli desetinu od svega; on koji u prijevodu znači najprije “kralj pravednosti”, a zatim i kralj šalemski, to jest “kralj mira”;"},{"v":3,"t":"on, bez oca, bez majke, bez rodoslovlja; on, kojemu dani nemaju početka ni život kraja - sličan Sinu Božjemu, ostaje svećenik zasvagda."},{"v":4,"t":"Pa promotrite koliki li je taj komu Abraham, rodozačetnik, dade desetinu od najboljega."},{"v":5,"t":"Istina, i oni sinovi Levijevi, koji primaju svećeništvo imaju zakonsku zapovijed da ubiru desetinu od naroda, to jest od svoje braće premda su i ona izašla iz boka Abrahamova."},{"v":6,"t":"Ali on, koji nije iz njihova rodoslovlja, ubra desetinu od Abrahama i blagoslovi njega, nosioca obećanja!"},{"v":7,"t":"A posve je neprijeporno: veći blagoslivlja manjega."},{"v":8,"t":"K tome, ovdje desetinu primaju smrtni ljudi, a ondje onaj, za kojega se svjedoči da živi."},{"v":9,"t":"I u Abrahamu se, tako reći, ubire desetina i od Levija koji inače desetinu prima"},{"v":10,"t":"jer još bijaše u boku očevu kad mu u susret iziđe Melkisedek."},{"v":11,"t":"Da se dakle savršenstvo postiglo po levitskom svećeništvu - jer na temelju njega narod je dobio Zakon - koja bi onda bila potreba da se po redu Melkisedekovu postavi drugi svećenik i da se ne imenuje po redu Aronovu?"},{"v":12,"t":"Doista kad se mijenja svećeništvo, nužno se mijenja i Zakon."},{"v":13,"t":"Jer onaj o kojemu se to veli pripadao je drugom plemenu, od kojega se nitko nije posvetio žrtveniku."},{"v":14,"t":"Poznato je da je Gospodin naš potekao od Jude, plemena za koje Mojsije ništa ne reče s obzirom na svećenike."},{"v":15,"t":"To je još očitije ako se drugi svećenik postavlja po sličnosti s Melkisedekom:"},{"v":16,"t":"postao je svećenikom ne po Zakonu tjelesne uredbe, nego snagom neuništiva života."},{"v":17,"t":"Ta svjedoči se: Zauvijek ti si svećenik po redu Melkisedekovu."},{"v":18,"t":"Dokida se dakle prijašnja uredba zbog njezine nemoći i beskorisnosti -"},{"v":19,"t":"jer Zakon nije ništa priveo k savršenstvu - a uvodi se bolja nada, po kojoj se približujemo Bogu."},{"v":20,"t":"I to se nije zbilo bez zakletve. Jer oni su bez zakletve postali svećenicima,"},{"v":21,"t":"a on sa zakletvom Onoga koji mu reče: Zakleo se Gospodin i neće se pokajati: “Zauvijek ti si svećenik”."},{"v":22,"t":"Utoliko je Isus i postao jamac boljega Saveza."},{"v":23,"t":"K tomu, mnogo je bilo svećenika jer ih je smrt priječila trajno ostati."},{"v":24,"t":"A on, jer ostaje dovijeka, ima neprolazno svećeništvo."},{"v":25,"t":"Zato i može do kraja spasavati one koji po njemu pristupaju k Bogu - uvijek živ da se za njih zauzima."},{"v":26,"t":"Takav nam Veliki svećenik i bijaše potreban - svet, nedužan, neokaljan, odijeljen od grešnika i uzvišeniji od nebesa -"},{"v":27,"t":"koji ne treba da kao oni veliki svećenici danomice prinosi žrtve najprije za svoje grijehe, a onda za grijehe naroda. To on učini jednom prinijevši samoga sebe."},{"v":28,"t":"Zakon doista postavi za velike svećenike ljude podložne slabosti, a riječ zakletve - nakon Zakona - Sina zauvijek usavršena."}]},"8":{"fa":[{"v":1,"t":"پس مقصود عمده از این کلام این است که برای ما چنین رئیس کهنه‌ای هست که درآسمانها به‌دست راست تخت کبریا نشسته است،"},{"v":2,"t":"که خادم مکان اقدس و آن خیمه حقیقی است که خداوند آن را برپا نمود نه انسان."},{"v":3,"t":"زیرا که هررئیس کهنه مقرر می‌شود تا هدایا و قربانی هابگذراند؛ و از این جهت واجب است که او را نیزچیزی باشد که بگذراند."},{"v":4,"t":"پس اگر بر زمین می بود، کاهن نمی بود چون کسانی هستند که به قانون شریعت هدایا را می‌گذرانند."},{"v":5,"t":"و ایشان شبیه و سایه چیزهای آسمانی را خدمت می‌کنند، چنانکه موسی ملهم شد هنگامی که عازم بود که خیمه را بسازد، زیرا بدو می‌گوید: «آگاه باش که همه‌چیز را به آن نمونه‌ای که در کوه به تو نشان داده شد بسازی.»"},{"v":6,"t":"لکن الان او خدمت نیکوتر یافته است، به مقداری که متوسط عهدنیکوتر نیز هست که بر وعده های نیکوتر مرتب است."},{"v":7,"t":"زیرا اگر آن اول بی‌عیب می‌بود، جایی برای دیگری طلب نمی شد."},{"v":8,"t":"چنانکه ایشان را ملامت کرده، می‌گوید: «خداوند می‌گوید اینک ایامی می‌آید که با خاندان اسرائیل و خاندان یهوداعهدی تازه استوار خواهم نمود."},{"v":9,"t":"نه مثل آن عهدی که با پدران ایشان بستم، در روزی که من ایشان را دستگیری نمودم تا از زمین مصربرآوردم، زیرا که ایشان در عهد من ثابت نماندند. پس خداوند می‌گوید من ایشان را واگذاردم."},{"v":10,"t":"وخداوند می‌گوید این است آن عهدی که بعد از آن ایام با خاندان اسرائیل استوار خواهم داشت که احکام خود را در خاطر ایشان خواهم نهاد و بردل ایشان مرقوم خواهم داشت و ایشان را خداخواهم بود و ایشان مرا قوم خواهند بود."},{"v":11,"t":"ودیگر کسی همسایه و برادر خود را تعلیم نخواهدداد و نخواهد گفت خداوند را بشناس زیرا که همه از خرد و بزرگ مرا خواهند شناخت."},{"v":12,"t":"زیرابر تقصیرهای ایشان ترحم خواهم فرمود وگناهانشان را دیگر به یاد نخواهم آورد.»"},{"v":13,"t":"پس چون «تازه» گفت، اول را کهنه ساخت؛ و آنچه کهنه و پیر شده است، مشرف بر زوال است."}],"en":[{"v":1,"t":"Now in the things which we are saying, the main point is this: we have such a high priest, who sat down on the right hand of the throne of the Majesty in the heavens,"},{"v":2,"t":"a servant of the sanctuary and of the true tabernacle which the Lord pitched, not man."},{"v":3,"t":"For every high priest is appointed to offer both gifts and sacrifices. Therefore it is necessary that this high priest also have something to offer."},{"v":4,"t":"For if he were on earth, he would not be a priest at all, seeing there are priests who offer the gifts according to the law,"},{"v":5,"t":"who serve a copy and shadow of the heavenly things, even as Moses was warned by God when he was about to make the tabernacle, for he said, “See, you shall make everything according to the pattern that was shown to you on the mountain.”"},{"v":6,"t":"But now he has obtained a more excellent ministry, by as much as he is also the mediator of a better covenant, which on better promises has been given as law."},{"v":7,"t":"For if that first covenant had been faultless, then no place would have been sought for a second."},{"v":8,"t":"For finding fault with them, he said, “Behold, the days are coming”, says the Lord, “that I will make a new covenant with the house of Israel and with the house of Judah;"},{"v":9,"t":"not according to the covenant that I made with their fathers in the day that I took them by the hand to lead them out of the land of Egypt; for they didn’t continue in my covenant, and I disregarded them,” says the Lord."},{"v":10,"t":"“For this is the covenant that I will make with the house of Israel after those days,” says the Lord: “I will put my laws into their mind; I will also write them on their heart. I will be their God, and they will be my people."},{"v":11,"t":"They will not teach every man his fellow citizen and every man his brother, saying, ‘Know the Lord,’ for all will know me, from their least to their greatest."},{"v":12,"t":"For I will be merciful to their unrighteousness. I will remember their sins and lawless deeds no more.”"},{"v":13,"t":"In that he says, “A new covenant”, he has made the first obsolete. But that which is becoming obsolete and grows aged is near to vanishing away."}],"hr":[{"v":1,"t":"A glavno u ovom izlaganju jest: takva imamo Velikog svećenika koji sjede zdesna prijestolja Veličanstva na nebesima"},{"v":2,"t":"kao bogoslužnik Svetinje i Šatora istinskoga što ga podiže Gospodin, a ne čovjek."},{"v":3,"t":"Doista, svaki se veliki svećenik postavlja da prinosi darove i žrtve. Odatle je potrebno da i on ima što bi prinio."},{"v":4,"t":"Svakako, da je na zemlji, ne bi bio svećenik jer postoje oni koji po Zakonu prinose darove."},{"v":5,"t":"Oni služe slici i sjeni onoga nebeskoga, kako je upućen Mojsije kad se spremao praviti šator: Pazi, veli doista, načini sve po praliku koji ti je pokazan na brdu."},{"v":6,"t":"Ovako mu pak dopalo uzvišenije bogosluženje koliko je Posrednik boljega Saveza, koji je uzakonjen na boljim obećanjima."},{"v":7,"t":"Da je, zbilja, onaj prvi bio besprijekoran, ne bi se drugome tražilo mjesto."},{"v":8,"t":"Doista, kudeći ih veli: Evo dolaze dani - govori Gospodin - kad ću s domom Izraelovim i s domom Judinim dovršiti novi Savez."},{"v":9,"t":"Ne Savez kakav učinih s ocima njihovim u dan kad ih uzeh za ruku da ih izvedem iz zemlje egipatske jer oni ne ustrajaše u mom Savezu pa i ja zanemarih njih - govori Gospodin."},{"v":10,"t":"Nego, ovo je Savez kojim ću se svezati s domom Izraelovim nakon ovih dana - govori Gospodin: Zakone ću svoje staviti u dušu njihovu i upisati ih u njihova srca. I bit ću Bog njihov, a oni narod moj."},{"v":11,"t":"I neće više nitko učiti sugrađanina i nitko brata svoga govoreći: “Spoznaj Gospodina”, ta svi će me poznavati, malo i veliko,"},{"v":12,"t":"jer ću se smilovati bezakonjima njihovim i grijeha se njihovih neću više spominjati."},{"v":13,"t":"Kad veli novi, ostari onaj prvi. Što pak stÓari i dotrajava, blizu je nestanku."}]},"9":{"fa":[{"v":1,"t":"خلاصه آن عهد اول را نیز فرایض خدمت و قدس دنیوی بود."},{"v":2,"t":"زیرا خیمه اول نصب شد که در آن بود چراغدان و میز و نان تقدمه، و آن به قدس مسمی گردید."},{"v":3,"t":"و در پشت پرده دوم بودآن خیمه‌ای که به قدس‌الاقداس مسمی است،"},{"v":4,"t":"که در آن بود مجمره زرین و تابوت شهادت که همه اطرافش به طلا آراسته بود؛ و در آن بود حقه طلا که پر از من بود و عصای هارون که شکوفه آورده بود و دو لوح عهد."},{"v":5,"t":"و بر زبر آن کروبیان جلال که بر تخت رحمت سایه‌گستر می‌بودند والان جای تفصیل آنها نیست."},{"v":6,"t":"پس چون این چیزها بدینطور آراسته شد، کهنه بجهت ادای لوازم خدمت، پیوسته به خیمه اول درمی آیند."},{"v":7,"t":"لکن در دوم سالی یک مرتبه رئیس کهنه‌تنها داخل می‌شود؛ و آن هم نه بدون خونی که برای خود و برای جهالات قوم می‌گذراند."},{"v":8,"t":"که به این همه روح‌القدس اشاره می‌نماید بر اینکه مادامی که خیمه اول برپاست، راه مکان اقدس ظاهر نمی شود."},{"v":9,"t":"و این مثلی است برای زمان حاضر که بحسب آن هدایا وقربانی‌ها را می‌گذرانند که قوت ندارد که عبادت‌کننده را از جهت ضمیر کامل گرداند،"},{"v":10,"t":"چونکه اینها با چیزهای خوردنی و آشامیدنی و طهارات مختلفه، فقط فرایض جسدی است که تا زمان اصلاح مقرر شده است."},{"v":11,"t":"لیکن مسیح چون ظاهر شد تا رئیس کهنه نعمتهای آینده باشد، به خیمه بزرگتر و کاملتر وناساخته شده به‌دست یعنی که از این خلقت نیست،"},{"v":12,"t":"و نه به خون بزها و گوساله‌ها، بلکه به خون خود، یک مرتبه فقط به مکان اقدس داخل شد و فدیه ابدی را یافت."},{"v":13,"t":"زیرا هر گاه خون بزها و گاوان و خاکستر گوساله چون بر آلودگان پاشیده می‌شود، تا به طهارت جسمی مقدس می‌سازد،"},{"v":14,"t":"پس آیا چند مرتبه زیاده، خون مسیح که به روح ازلی خویشتن را بی‌عیب به خداگذرانید، ضمیر شما را از اعمال مرده طاهرنخواهد ساخت تا خدای زنده را خدمت نمایید؟"},{"v":15,"t":"و از این جهت او متوسط عهد تازه‌ای است تا چون موت برای کفاره تقصیرات عهد اول بوقوع آمد، خوانده‌شدگان وعده میراث ابدی رابیابند."},{"v":16,"t":"زیرا در هر جایی که وصیتی است، لابداست که موت وصیت‌کننده را تصور کنند،"},{"v":17,"t":"زیرا که وصیت بعد از موت ثابت می‌شود؛ زیرامادامی که وصیت‌کننده زنده است، استحکامی ندارد."},{"v":18,"t":"و از اینرو، آن اول نیز بدون خون برقرارنشد."},{"v":19,"t":"زیرا که چون موسی تمامی احکام رابحسب شریعت، به سمع قوم رسانید، خون گوساله‌ها و بزها را با آب و پشم قرمز و زوفاگرفته، آن را بر خود کتاب و تمامی قوم پاشید؛"},{"v":20,"t":"و گفت: «این است خون آن عهدی که خداباشما قرار داد.»"},{"v":21,"t":"و همچنین خیمه و جمیع آلات خدمت را نیز به خون بیالود."},{"v":22,"t":"و بحسب شریعت، تقریب همه‌چیز به خون طاهر می‌شود وبدون ریختن خون، آمرزش نیست."},{"v":23,"t":"پس لازم بود که مثل های چیزهای سماوی به اینها طاهر شود، لکن خود سماویات به قربانی های نیکوتر از اینها."},{"v":24,"t":"زیرا مسیح به قدس ساخته شده به‌دست داخل نشد که مثال مکان حقیقی است؛ بلکه به خود آسمان تا آنکه الان درحضور خدا بجهت ما ظاهر شود."},{"v":25,"t":"و نه آنکه جان خود را بارها قربانی کند، مانند آن رئیس کهنه که هر سال با خون دیگری به مکان اقدس داخل می‌شود؛"},{"v":26,"t":"زیرا در این صورت می‌بایست که او از بنیاد عالم بارها زحمت کشیده باشد. لکن الان یک مرتبه در اواخر عالم ظاهر شد تا به قربانی خود، گناه را محو سازد."},{"v":27,"t":"و چنانکه مردم را یک بار مردن و بعد از آن جزا یافتن مقرر است،"},{"v":28,"t":"همچنین مسیح نیز چون یک بار قربانی شد تاگناهان بسیاری را رفع نماید، بار دیگر بدون گناه، برای کسانی که منتظر او می‌باشند، ظاهر خواهدشد بجهت نجات."}],"en":[{"v":1,"t":"Now indeed even the first covenant had ordinances of divine service and an earthly sanctuary."},{"v":2,"t":"For a tabernacle was prepared. In the first part were the lamp stand, the table, and the show bread, which is called the Holy Place."},{"v":3,"t":"After the second veil was the tabernacle which is called the Holy of Holies,"},{"v":4,"t":"having a golden altar of incense and the ark of the covenant overlaid on all sides with gold, in which was a golden pot holding the manna, Aaron’s rod that budded, and the tablets of the covenant;"},{"v":5,"t":"and above it cherubim of glory overshadowing the mercy seat, of which things we can’t speak now in detail."},{"v":6,"t":"Now these things having been thus prepared, the priests go in continually into the first tabernacle, accomplishing the services,"},{"v":7,"t":"but into the second the high priest alone, once in the year, not without blood, which he offers for himself and for the errors of the people."},{"v":8,"t":"The Holy Spirit is indicating this, that the way into the Holy Place wasn’t yet revealed while the first tabernacle was still standing."},{"v":9,"t":"This is a symbol of the present age, where gifts and sacrifices are offered that are incapable, concerning the conscience, of making the worshiper perfect,"},{"v":10,"t":"being only (with foods and drinks and various washings) fleshly ordinances, imposed until a time of reformation."},{"v":11,"t":"But Christ having come as a high priest of the coming good things, through the greater and more perfect tabernacle, not made with hands, that is to say, not of this creation,"},{"v":12,"t":"nor yet through the blood of goats and calves, but through his own blood, entered in once for all into the Holy Place, having obtained eternal redemption."},{"v":13,"t":"For if the blood of goats and bulls, and the ashes of a heifer sprinkling those who have been defiled, sanctify to the cleanness of the flesh,"},{"v":14,"t":"how much more will the blood of Christ, who through the eternal Spirit offered himself without defect to God, cleanse your conscience from dead works to serve the living God?"},{"v":15,"t":"For this reason he is the mediator of a new covenant, since a death has occurred for the redemption of the transgressions that were under the first covenant, that those who have been called may receive the promise of the eternal inheritance."},{"v":16,"t":"For where a last will and testament is, there must of necessity be the death of him who made it."},{"v":17,"t":"For a will is in force where there has been death, for it is never in force while he who made it lives."},{"v":18,"t":"Therefore even the first covenant has not been dedicated without blood."},{"v":19,"t":"For when every commandment had been spoken by Moses to all the people according to the law, he took the blood of the calves and the goats, with water and scarlet wool and hyssop, and sprinkled both the book itself and all the people,"},{"v":20,"t":"saying, “This is the blood of the covenant which God has commanded you.”"},{"v":21,"t":"He sprinkled the tabernacle and all the vessels of the ministry in the same way with the blood."},{"v":22,"t":"According to the law, nearly everything is cleansed with blood, and apart from shedding of blood there is no remission."},{"v":23,"t":"It was necessary therefore that the copies of the things in the heavens should be cleansed with these, but the heavenly things themselves with better sacrifices than these."},{"v":24,"t":"For Christ hasn’t entered into holy places made with hands, which are representations of the true, but into heaven itself, now to appear in the presence of God for us;"},{"v":25,"t":"nor yet that he should offer himself often, as the high priest enters into the holy place year by year with blood not his own,"},{"v":26,"t":"or else he must have suffered often since the foundation of the world. But now once at the end of the ages, he has been revealed to put away sin by the sacrifice of himself."},{"v":27,"t":"Inasmuch as it is appointed for men to die once, and after this, judgment,"},{"v":28,"t":"so Christ also, having been offered once to bear the sins of many, will appear a second time, not to deal with sin, but to save those who are eagerly waiting for him."}],"hr":[{"v":1,"t":"I onaj prvi je, svakako, imao bogoštovne uredbe i Svetinju, ali ovosvjetsku."},{"v":2,"t":"Šator je uistinu bio uređen: prvi, u kojem bijaše svijećnjak, stol i prinos kruhova, a zove se Svetinja;"},{"v":3,"t":"iza druge pak zavjese bio je Šator zvan Svetinja nad svetinjama -"},{"v":4,"t":"u njoj zlatni kadionik i Kovčeg saveza, sav optočen zlatom, a u njemu zlatna posuda s manom i štap Aronov, koji je ono procvao, i ploče Saveza;"},{"v":5,"t":"povrh njega pak kerubi Slave što osjenjuju Pomirilište. O tom ne treba sada potanko govoriti."},{"v":6,"t":"Pošto je to tako uređeno, u prvi Šator stalno ulaze svećenici obavljati bogoslužje,"},{"v":7,"t":"a u drugi jednom godišnje samo veliki svećenik, i to ne bez krvi koju prinosi za sebe i za nepažnje naroda."},{"v":8,"t":"Time Duh Sveti očituje da još nije otkriven put u Svetinju dok još postoji prvi Šator."},{"v":9,"t":"To je slika za sadašnje vrijeme: prinose se darovi i žrtve koje ne mogu u savjesti usavršiti bogoslužnika -"},{"v":10,"t":"sve same na ićima i pićima i raznim pranjima utemeljene tjelesne uredbe, nametnute do časa ispravka."},{"v":11,"t":"Krist se pak pojavi kao Veliki svećenik budućih dobara pa po većem i savršenijem Šatoru - nerukotvorenu, koji nije od ovoga stvorenja -"},{"v":12,"t":"i ne po krvi jaraca i junaca, nego po svojoj uđe jednom zauvijek u Svetinju i nađe vječno otkupljenje."},{"v":13,"t":"Doista, ako već poškropljena krv jaraca i bikova i pepeo juničin posvećuje onečišćene, daje tjelesnu čistoću,"},{"v":14,"t":"koliko će više krv Krista - koji po Duhu vječnom samoga sebe bez mane prinese Bogu - očistiti savjest našu od mrtvih djela, na službu Bogu živomu!"},{"v":15,"t":"A radi ovoga je Posrednik novoga Saveza: da po smrti za otkupljenje prekršaja iz starog Saveza pozvani zadobiju obećanu vječnu baštinu."},{"v":16,"t":"Jer gdje je posrijedi savez-oporuka, potrebno je dokazati smrt oporučitelja."},{"v":17,"t":"Oporuka je doista valjana tek nakon smrti: nikad ne vrijedi dok oporučitelj živi."},{"v":18,"t":"Stoga ni onaj prvi Savez nije bez krvi ustanovljen."},{"v":19,"t":"Pošto je svemu narodu priopćio svaku zapovijed zakonsku, uze Mojsije krv junaca i jaraca s vodom i grimiznom vunom i izopom te samu Knjigu i sav narod poškropi"},{"v":20,"t":"govoreći: Ovo je krv Saveza koji vam odredi Bog;"},{"v":21,"t":"a onda krvlju slično poškropi i Šator i sve bogoslužno posuđe."},{"v":22,"t":"I gotovo se sve po zakonu čisti krvlju i bez prolijevanja krvi nema oproštenja."},{"v":23,"t":"Ako se dakle time čiste slike onoga što je na nebu, potrebno je da se samo to nebesko čisti žrtvama od tih uspješnijima."},{"v":24,"t":"Krist doista ne uđe u rukotvorenu Svetinju, protulik one istinske, nego u samo nebo: da se sada pojavi pred licem Božjim za nas."},{"v":25,"t":"Ne da mnogo puta prinosi samoga sebe kao što veliki svećenik svake godine ulazi u Svetinju s tuđom krvlju;"},{"v":26,"t":"inače bi bilo trebalo da trpi mnogo puta od postanka svijeta. No sada se pojavio, jednom na svršetku vjekova, da grijeh dokine žrtvom svojom."},{"v":27,"t":"I kao što je ljudima jednom umrijeti, a potom na sud,"},{"v":28,"t":"tako i Krist: jednom se prinese da grijehe mnogih ponese, a drugi će se put - bez obzira na grijeh - ukazati onima koji ga iščekuju sebi na spasenje."}]},"10":{"fa":[{"v":1,"t":"زیرا که چون شریعت را سایه نعمتهای آینده است، نه نفس صورت آن چیزها، آن هرگز نمی تواند هر سال به همان قربانی هایی که پیوسته می‌گذرانند، تقرب جویندگان را کامل گرداند."},{"v":2,"t":"والا آیا گذرانیدن آنها موقوف نمی شدچونکه عبادت‌کنندگان، بعد از آنکه یک بار پاک شدند، دیگر حس گناهان را در ضمیر نمی داشتند؟"},{"v":3,"t":"بلکه در اینها هر سال یادگاری گناهان می‌شود."},{"v":4,"t":"زیرا محال است که خون گاوهاو بزها رفع گناهان را بکند."},{"v":5,"t":"لهذا هنگامی که داخل جهان می‌شود، می‌گوید: «قربانی و هدیه را نخواستی، لکن جسدی برای من مهیا ساختی."},{"v":6,"t":"به قربانی های سوختنی و قربانی های گناه رغبت نداشتی."},{"v":7,"t":"آنگاه گفتم، اینک می‌آیم (در طومار کتاب درحق من مکتوب است ) تا اراده تو را‌ای خدا بجاآورم.»"},{"v":8,"t":"چون پیش می‌گوید: «هدایا و قربانی‌ها وقربانی های سوختنی و قربانی های گناه رانخواستی و به آنها رغبت نداشتی، » که آنها رابحسب شریعت می‌گذرانند،"},{"v":9,"t":"بعد گفت که «اینک می‌آیم تا اراده تو را‌ای خدا بجا آورم.» پس اول را برمی دارد، تا دوم را استوار سازد."},{"v":10,"t":"و به این اراده مقدس شده‌ایم، به قربانی جسد عیسی مسیح، یک مرتبه فقط."},{"v":11,"t":"و هر کاهن هر روزه به خدمت مشغول بوده، می‌ایستد وهمان قربانی‌ها را مکرر می‌گذراند که هرگز رفع گناهان را نمی تواند کرد."},{"v":12,"t":"لکن او چون یک قربانی برای گناهان گذرانید، به‌دست راست خدابنشست تا ابدالاباد."},{"v":13,"t":"و بعد از آن منتظر است تادشمنانش پای انداز او شوند."},{"v":14,"t":"از آنرو که به یک قربانی مقدسان را کامل گردانیده است تا ابدالاباد."},{"v":15,"t":"و روح‌القدس نیزبرای ما شهادت می‌دهد، زیرا بعد از آنکه گفته بود:"},{"v":16,"t":"«این است آن عهدی که بعد از آن ایام باایشان خواهم بست، خداوند می‌گوید احکام خود را در دلهای ایشان خواهم نهاد و بر ذهن ایشان مرقوم خواهم داشت،"},{"v":17,"t":"(باز می‌گوید) وگناهان و خطایای ایشان را دیگر به یاد نخواهم آورد.»"},{"v":18,"t":"اما جایی که آمرزش اینها هست، دیگرقربانی گناهان نیست."},{"v":19,"t":"پس‌ای برادران، چونکه به خون عیسی دلیری داریم تا به مکان اقدس داخل شویم"},{"v":20,"t":"ازطریق تازه و زنده که آن را بجهت ما از میان پرده یعنی جسم خود مهیا نموده است،"},{"v":21,"t":"و کاهنی بزرگ را بر خانه خدا داریم،"},{"v":22,"t":"پس به دل راست، در یقین ایمان، دلهای خود را از ضمیر بد پاشیده و بدنهای خود را به آب پاک غسل داده، نزدیک بیاییم؛"},{"v":23,"t":"و اعتراف امید را محکم نگاه داریم زیراکه وعده‌دهنده امین است."},{"v":24,"t":"و ملاحظه یکدیگررا بنماییم تا به محبت و اعمال نیکو ترغیب نماییم."},{"v":25,"t":"و از با هم آمدن در جماعت غافل نشویم چنانکه بعضی را عادت است، بلکه یکدیگر را نصیحت کنیم و زیادتر به اندازه‌ای که می‌بینید که آن روز نزدیک می‌شود."},{"v":26,"t":"زیرا که بعد از پذیرفتن معرفت راستی اگرعمد گناهکار شویم، دیگر قربانی گناهان باقی نیست،"},{"v":27,"t":"بلکه انتظار هولناک عذاب و غیرت آتشی که مخالفان را فرو خواهد برد."},{"v":28,"t":"هر‌که شریعت موسی را خوار شمرد، بدون رحم به دویا سه شاهد کشته می‌شود."},{"v":29,"t":"پس به چه مقدارگمان می‌کنید که آن کس، مستحق عقوبت سخت‌تر شمرده خواهد شد که پسر خدا راپایمال کرد و خون عهدی را که به آن مقدس گردانیده شد، ناپاک شمرد و روح نعمت رابی حرمت کرد؟"},{"v":30,"t":"زیرا می‌شناسیم او را که گفته است: «خداوند می‌گوید انتقام از آن من است؛ من مکافات خواهم داد.» و ایض: «خداوند قوم خودرا داوری خواهد نمود.»"},{"v":31,"t":"افتادن به‌دستهای خدای زنده چیزی هولناک است."},{"v":32,"t":"ولیکن ایام سلف را به یاد آورید که بعد ازآنکه منور گردیدید، متحمل مجاهده‌ای عظیم ازدردها شدید،"},{"v":33,"t":"چه از اینکه از دشنامها وزحمات تماشای مردم می‌شدید، و چه از آنکه شریک با کسانی می‌بودید که در چنین چیزها بسرمی بردند."},{"v":34,"t":"زیرا که با اسیران نیز همدردمی بودید و تاراج اموال خود را نیز به خوشی می‌پذیرفتید، چون دانستید که خود شما را درآسمان مال نیکوتر و باقی است."},{"v":35,"t":"پس ترک مکنید دلیری خود را که مقرون به مجازات عظیم می‌باشد."},{"v":36,"t":"زیرا که شما را صبر لازم است تااراده خدا را بجا آورده، وعده را بیابید."},{"v":37,"t":"زیرا که «بعد از اندک زمانی، آن آینده خواهد آمد وتاخیر نخواهد نمود."},{"v":38,"t":"لکن عادل به ایمان زیست خواهد نمود و اگر مرتد شود نفس من باوی خوش نخواهد شد.»"},{"v":39,"t":"لکن ما از مرتدان نیستیم تا هلاک شویم، بلکه از ایمانداران تا جان خود را دریابیم."}],"en":[{"v":1,"t":"For the law, having a shadow of the good to come, not the very image of the things, can never with the same sacrifices year by year, which they offer continually, make perfect those who draw near."},{"v":2,"t":"Or else wouldn’t they have ceased to be offered, because the worshipers, having been once cleansed, would have had no more consciousness of sins?"},{"v":3,"t":"But in those sacrifices there is a yearly reminder of sins."},{"v":4,"t":"For it is impossible that the blood of bulls and goats should take away sins."},{"v":5,"t":"Therefore when he comes into the world, he says, “You didn’t desire sacrifice and offering, but you prepared a body for me."},{"v":6,"t":"You had no pleasure in whole burnt offerings and sacrifices for sin."},{"v":7,"t":"Then I said, ‘Behold, I have come (in the scroll of the book it is written of me) to do your will, O God.’”"},{"v":8,"t":"Previously saying, “Sacrifices and offerings and whole burnt offerings and sacrifices for sin you didn’t desire, neither had pleasure in them” (those which are offered according to the law),"},{"v":9,"t":"then he has said, “Behold, I have come to do your will.” He takes away the first, that he may establish the second,"},{"v":10,"t":"by which will we have been sanctified through the offering of the body of Jesus Christ once for all."},{"v":11,"t":"Every priest indeed stands day by day serving and offering often the same sacrifices, which can never take away sins,"},{"v":12,"t":"but he, when he had offered one sacrifice for sins forever, sat down on the right hand of God,"},{"v":13,"t":"from that time waiting until his enemies are made the footstool of his feet."},{"v":14,"t":"For by one offering he has perfected forever those who are being sanctified."},{"v":15,"t":"The Holy Spirit also testifies to us, for after saying,"},{"v":16,"t":"“This is the covenant that I will make with them after those days,” says the Lord, “I will put my laws on their heart, I will also write them on their mind;” then he says,"},{"v":17,"t":"“I will remember their sins and their iniquities no more.”"},{"v":18,"t":"Now where remission of these is, there is no more offering for sin."},{"v":19,"t":"Having therefore, brothers, boldness to enter into the holy place by the blood of Jesus,"},{"v":20,"t":"by the way which he dedicated for us, a new and living way, through the veil, that is to say, his flesh,"},{"v":21,"t":"and having a great priest over God’s house,"},{"v":22,"t":"let’s draw near with a true heart in fullness of faith, having our hearts sprinkled from an evil conscience and having our body washed with pure water,"},{"v":23,"t":"let’s hold fast the confession of our hope without wavering; for he who promised is faithful."},{"v":24,"t":"Let’s consider how to provoke one another to love and good works,"},{"v":25,"t":"not forsaking our own assembling together, as the custom of some is, but exhorting one another, and so much the more as you see the Day approaching."},{"v":26,"t":"For if we sin willfully after we have received the knowledge of the truth, there remains no more a sacrifice for sins,"},{"v":27,"t":"but a certain fearful expectation of judgment, and a fierceness of fire which will devour the adversaries."},{"v":28,"t":"A man who disregards Moses’ law dies without compassion on the word of two or three witnesses."},{"v":29,"t":"How much worse punishment do you think he will be judged worthy of who has trodden under foot the Son of God, and has counted the blood of the covenant with which he was sanctified an unholy thing, and has insulted the Spirit of grace?"},{"v":30,"t":"For we know him who said, “Vengeance belongs to me. I will repay,” says the Lord. Again, “The Lord will judge his people.”"},{"v":31,"t":"It is a fearful thing to fall into the hands of the living God."},{"v":32,"t":"But remember the former days, in which, after you were enlightened, you endured a great struggle with sufferings:"},{"v":33,"t":"partly, being exposed to both reproaches and oppressions, and partly, becoming partakers with those who were treated so."},{"v":34,"t":"For you both had compassion on me in my chains and joyfully accepted the plundering of your possessions, knowing that you have for yourselves a better possession and an enduring one in the heavens."},{"v":35,"t":"Therefore don’t throw away your boldness, which has a great reward."},{"v":36,"t":"For you need endurance so that, having done the will of God, you may receive the promise."},{"v":37,"t":"“In a very little while, he who comes will come and will not wait."},{"v":38,"t":"But the righteous one will live by faith. If he shrinks back, my soul has no pleasure in him.”"},{"v":39,"t":"But we are not of those who shrink back to destruction, but of those who have faith to the saving of the soul."}],"hr":[{"v":1,"t":"Budući da Zakon ima tek sjenu budućih dobara, a ne sam lik zbiljnosti, on uistinu žrtvama koje se - iz godine u godinu iste - neprestano prinose ne može nikada usavršiti one što pristupaju."},{"v":2,"t":"Ta ne bi li se prestale prinositi kad bogoslužnici, jednom očišćeni, ne bi više imali nikakve svijesti grijeha?"},{"v":3,"t":"Ali po njima se iz godine u godinu podsjeća na grijehe."},{"v":4,"t":"Jer krv bikova i jaraca nikako ne može odnijeti grijeha."},{"v":5,"t":"Zato On ulazeći u svijet veli: Žrtva i prinos ne mile ti se, nego si mi tijelo pripravio;"},{"v":6,"t":"paljenice i okajnice ne sviđaju ti se."},{"v":7,"t":"Tada rekoh: “Evo dolazim!” U svitku knjige piše za mene: “Vršiti, Bože, volju tvoju!”"},{"v":8,"t":"Pošto gore reče: Žrtve i prinosi, paljenice i okajnice - koje se po Zakonu prinose - ne mile ti se i ne sviđaju,"},{"v":9,"t":"veli zatim: Evo dolazim vršiti volju tvoju! Dokida prvo da uspostavi drugo."},{"v":10,"t":"U toj smo volji posvećeni prinosom tijela Isusa Krista jednom zauvijek."},{"v":11,"t":"I svaki je svećenik dan za danom u bogoslužju te učestalo prinosi iste žrtve, koje nikako ne mogu odnijeti grijeha."},{"v":12,"t":"A ovaj, pošto je prinio jednu jedincatu žrtvu za grijehe, zauvijek sjede zdesna Bogu"},{"v":13,"t":"čekajući otad dok se neprijatelji ne podlože za podnožje nogama njegovim."},{"v":14,"t":"Jednim uistinu prinosom zasvagda usavrši posvećene."},{"v":15,"t":"A to nam svjedoči i Duh Sveti. Pošto je doista rekao:"},{"v":16,"t":"“Ovo je Savez kojim ću se svezati s njima nakon ovih dana”, Gospodin govori: “Zakone ću svoje staviti u njihova srca i upisati ih u dušu njihovu."},{"v":17,"t":"I grijeha se njihovih i bezakonja njihovih neću više spominjati.”"},{"v":18,"t":"A gdje su grijesi oprošteni, nema više prinosa za njih."},{"v":19,"t":"Imamo dakle, braćo, slobodan ulaz u Svetinju po krvi Isusovoj -"},{"v":20,"t":"put nov i živ što nam ga On otvori kroz zavjesu, to jest svoje tijelo;"},{"v":21,"t":"imamo i Velikog svećenika nad kućom Božjom."},{"v":22,"t":"Pristupajmo stoga s istinitim srcem u punini vjere, srdaca škropljenjem očišćenih od zle savjesti i tijela oprana čistom vodom."},{"v":23,"t":"Čuvajmo nepokolebljivu vjeru nade jer je vjeran Onaj koji dade obećanje."},{"v":24,"t":"I pazimo jedni na druge da se potičemo na ljubav i dobra djela"},{"v":25,"t":"te ne propuštamo svojih sastanaka, kako je u nekih običaj, nego se hrabrimo, to više što više vidite da se bliži Dan."},{"v":26,"t":"Jer ako svojevoljno griješimo pošto primismo spoznanje istine, nema više žrtve za grijehe,"},{"v":27,"t":"nego strašno isčekivanje suda i bijesa ognja što će proždrijeti protivnike."},{"v":28,"t":"Je li tko prekršio Zakon Mojsijev, bez milosrđa biva pogubljen na osnovi dvojice ili trojice svjedoka."},{"v":29,"t":"Zamislite koliko li će goru kaznu zavrijediti tko Sina Božjega pogazi, i nečistom smatra krv Saveza kojom je posvećen, i Duha milosti pogrdi?"},{"v":30,"t":"Ta poznajemo Onoga koji je rekao: Moja je odmazda, ja ću je vratiti; i još: Sudit će Gospodin svome puku."},{"v":31,"t":"Strašno je upasti u ruke Boga živoga."},{"v":32,"t":"A spomenite se onih prvih dana kada ste, tek prosvijetljeni, izdržali veliku patničku borbu:"},{"v":33,"t":"ovamo javno izvrgnuti porugama i nevoljama, onamo postavši zajedničari onih s kojima se tako postupalo."},{"v":34,"t":"I doista, sa sužnjevima ste suosjećali i s radošću prihvatili otimanje dobara znajući da imate bolji, trajan posjed."},{"v":35,"t":"Ne gubite dakle pouzdanja! Pripada mu velika plaća!"},{"v":36,"t":"Postojanosti vam uistinu treba da biste vršeći volju Božju zadobili obećano."},{"v":37,"t":"Jer još malo, sasvim malo, i Onaj koji dolazi doći će i neće zakasniti"},{"v":38,"t":"A pravednik će moj od vjere živjeti, ako li pak otpadne, ne mili se on duši mojoj."},{"v":39,"t":"A mi nismo od onih koji otpadaju, sebi na propast, nego od onih koji vjeruju na spas duše."}]},"11":{"fa":[{"v":1,"t":"پس ایمان، اعتماد بر چیزهای امید داشته شده است و برهان چیزهای نادیده."},{"v":2,"t":"زیرا که به این، برای قدما شهادت داده شد."},{"v":3,"t":"به ایمان فهمیده‌ایم که عالم‌ها به کلمه خدامرتب گردید، حتی آنکه چیزهای دیدنی ازچیزهای نادیدنی ساخته شد."},{"v":4,"t":"به ایمان هابیل قربانی نیکوتر از قائن را به خدا گذرانید و به‌سبب آن شهادت داده شد که عادل است، به آنکه خدا به هدایای او شهادت می‌دهد؛ و به‌سبب همان بعد از مردن هنوزگوینده است."},{"v":5,"t":"به ایمان خنوخ منتقل گشت تا موت را نبیندو نایاب شد چرا‌که خدا او را منتقل ساخت زیراقبل از انتقال وی شهادت داده شد که رضامندی خدا را حاصل کرد."},{"v":6,"t":"لیکن بدون ایمان تحصیل رضامندی او محال است، زیرا هر‌که تقرب به خدا جوید، لازم است که ایمان آورد بر اینکه اوهست و جویندگان خود را جزا می‌دهد."},{"v":7,"t":"به ایمان نوح چون درباره اموری که تا آن وقت دیده نشده، الهام یافته بود، خداترس شده، کشتی‌ای بجهت اهل خانه خود بساخت و به آن، دنیا را ملزم ساخته، وارث آن عدالتی که از ایمان است گردید."},{"v":8,"t":"به ایمان ابراهیم چون خوانده شد، اطاعت نمود و بیرون رفت به سمت آن مکانی که می‌بایست به میراث یابد. پس بیرون آمد ونمی دانست به کجا می‌رود."},{"v":9,"t":"و به ایمان در زمین وعده مثل زمین بیگانه غربت پذیرفت و درخیمه‌ها با اسحاق و یعقوب که در میراث همین وعده شریک بودند مسکن نمود."},{"v":10,"t":"زانرو که مترقب شهری بابنیاد بود که معمار و سازنده آن خداست."},{"v":11,"t":"به ایمان خود ساره نیز قوت قبول نسل یافت و بعد از انقضای وقت زایید، چونکه وعده‌دهنده را امین دانست."},{"v":12,"t":"و از این سبب، ازیک نفر و آن هم مرده، مثل ستارگان آسمان، کثیرو مانند ریگهای کنار دریا، بی‌شمار زاییده شدند."},{"v":13,"t":"در ایمان همه ایشان فوت شدند، درحالیکه وعده‌ها را نیافته بودند، بلکه آنها را از دوردیده، تحیت گفتند و اقرار کردند که بر روی زمین، بیگانه و غریب بودند."},{"v":14,"t":"زیرا کسانی که همچنین می‌گویند، ظاهر می‌سازند که در جستجوی وطنی هستند."},{"v":15,"t":"و اگر جایی را که از آن بیرون آمدند، بخاطر می‌آوردند، هرآینه فرصت می‌داشتند که (بدانجا) برگردند."},{"v":16,"t":"لکن الحال مشتاق وطنی نیکوتر یعنی (وطن ) سماوی هستند و از اینرو خدا از ایشان عار ندارد که خدای ایشان خوانده شود، چونکه برای ایشان شهری مهیا ساخته است."},{"v":17,"t":"به ایمان ابراهیم چون امتحان شد، اسحاق را گذرانید و آنکه وعده‌ها را پذیرفته بود، پسریگانه خود را قربانی می‌کرد؛"},{"v":18,"t":"که به او گفته شده بود که «نسل تو به اسحاق خوانده خواهد شد.»"},{"v":19,"t":"چونکه یقین دانست که خدا قادر بربرانگیزانیدن از اموات است و همچنین او را درمثلی از اموات نیز باز‌یافت."},{"v":20,"t":"به ایمان اسحاق نیز یعقوب و عیسو را درامور آینده برکت داد."},{"v":21,"t":"به ایمان یعقوب در وقت مردن خود، هریکی از پسران یوسف را برکت داد و بر سر عصای خود سجده کرد."},{"v":22,"t":"به ایمان یوسف در حین وفات خود، ازخروج بنی‌اسرائیل اخبار نمود و درباره استخوانهای خود وصیت کرد."},{"v":23,"t":"به ایمان موسی چون متولد شد، والدینش او را طفلی جمیل یافته، سه ماه پنهان کردند و ازحکم پادشاه بیم نداشتند."},{"v":24,"t":"به ایمان چون موسی بزرگ شد، ابا نمود ازاینکه پسر دختر فرعون خوانده شود،"},{"v":25,"t":"و ذلیل بودن با قوم خدا را پسندیده تر داشت از آنکه لذت اندک زمانی گناه را ببرد؛"},{"v":26,"t":"و عار مسیح رادولتی بزرگتر از خزائن مصر پنداشت زیرا که به سوی مجازات نظر می‌داشت."},{"v":27,"t":"به ایمان، مصررا ترک کرد و از غضب پادشاه نترسید زیرا که چون آن نادیده را بدید، استوار ماند."},{"v":28,"t":"به ایمان، عید فصح و پاشیدن خون را بعمل آورد تاهلاک کننده نخستزادگان، بر ایشان دست نگذارد."},{"v":29,"t":"به ایمان، از بحر قلزم به خشکی عبورنمودند واهل مصر قصد آن کرده، غرق شدند."},{"v":30,"t":"به ایمان حصار اریحا چون هفت روز آن راطواف کرده بودند، به زیر افتاد."},{"v":31,"t":"به ایمان، راحاب فاحشه با عاصیان هلاک نشد زیرا که جاسوسان را به سلامتی پذیرفته بود."},{"v":32,"t":"و دیگر‌چه گویم؟ زیرا که وقت مرا کفاف نمی دهد که از جدعون و باراق و شمشون و یفتاح و داود و سموئیل و انبیا اخبار نمایم،"},{"v":33,"t":"که ازایمان، تسخیر ممالک کردند و به اعمال صالحه پرداختند و وعده‌ها را پذیرفتند و دهان شیران رابستند،"},{"v":34,"t":"سورت آتش را خاموش کردند و از دم شمشیرها رستگار شدند و از ضعف، توانایی یافتند و در جنگ شجاع شدند و لشکرهای غربارا منهزم ساختند."},{"v":35,"t":"زنان، مردگان خود را به قیامتی باز‌یافتند، لکن دیگران معذب شدند وخلاصی را قبول نکردند تا به قیامت نیکوتربرسند."},{"v":36,"t":"و دیگران از استهزاها و تازیانه‌ها بلکه از بندها و زندان آزموده شدند."},{"v":37,"t":"سنگسارگردیدند و با اره دوپاره گشتند. تجربه کرده شدندو به شمشیر مقتول گشتند. در پوستهای گوسفندان و بزها محتاج و مظلوم و ذلیل و آواره شدند."},{"v":38,"t":"آنانی که جهان لایق ایشان نبود، درصحراها و کوهها و مغاره‌ها و شکافهای زمین پراکنده گشتند."},{"v":39,"t":"پس جمیع ایشان با اینکه از ایمان شهادت داده شدند، وعده را نیافتند."},{"v":40,"t":"زیرا خدا برای ماچیزی نیکوتر مهیا کرده است تا آنکه بدون ماکامل نشوند."}],"en":[{"v":1,"t":"Now faith is assurance of things hoped for, proof of things not seen."},{"v":2,"t":"For by this, the elders obtained approval."},{"v":3,"t":"By faith we understand that the universe has been framed by the word of God, so that what is seen has not been made out of things which are visible."},{"v":4,"t":"By faith Abel offered to God a more excellent sacrifice than Cain, through which he had testimony given to him that he was righteous, God testifying with respect to his gifts; and through it he, being dead, still speaks."},{"v":5,"t":"By faith Enoch was taken away, so that he wouldn’t see death, and he was not found, because God translated him. For he has had testimony given to him that before his translation he had been well pleasing to God."},{"v":6,"t":"Without faith it is impossible to be well pleasing to him, for he who comes to God must believe that he exists, and that he is a rewarder of those who seek him."},{"v":7,"t":"By faith Noah, being warned about things not yet seen, moved with godly fear, prepared a ship for the saving of his house, through which he condemned the world and became heir of the righteousness which is according to faith."},{"v":8,"t":"By faith Abraham, when he was called, obeyed to go out to the place which he was to receive for an inheritance. He went out, not knowing where he went."},{"v":9,"t":"By faith he lived as an alien in the land of promise, as in a land not his own, dwelling in tents with Isaac and Jacob, the heirs with him of the same promise."},{"v":10,"t":"For he was looking for the city which has foundations, whose builder and maker is God."},{"v":11,"t":"By faith even Sarah herself received power to conceive, and she bore a child when she was past age, since she counted him faithful who had promised."},{"v":12,"t":"Therefore as many as the stars of the sky in multitude, and as innumerable as the sand which is by the sea shore, were fathered by one man, and him as good as dead."},{"v":13,"t":"These all died in faith, not having received the promises, but having seen them and embraced them from afar, and having confessed that they were strangers and pilgrims on the earth."},{"v":14,"t":"For those who say such things make it clear that they are seeking a country of their own."},{"v":15,"t":"If indeed they had been thinking of that country from which they went out, they would have had enough time to return."},{"v":16,"t":"But now they desire a better country, that is, a heavenly one. Therefore God is not ashamed of them, to be called their God, for he has prepared a city for them."},{"v":17,"t":"By faith, Abraham, being tested, offered up Isaac. Yes, he who had gladly received the promises was offering up his only born son,"},{"v":18,"t":"to whom it was said, “Your offspring will be accounted as from Isaac,”"},{"v":19,"t":"concluding that God is able to raise up even from the dead. Figuratively speaking, he also did receive him back from the dead."},{"v":20,"t":"By faith Isaac blessed Jacob and Esau, even concerning things to come."},{"v":21,"t":"By faith Jacob, when he was dying, blessed each of the sons of Joseph, and worshiped, leaning on the top of his staff."},{"v":22,"t":"By faith Joseph, when his end was near, made mention of the departure of the children of Israel, and gave instructions concerning his bones."},{"v":23,"t":"By faith Moses, when he was born, was hidden for three months by his parents, because they saw that he was a beautiful child; and they were not afraid of the king’s commandment."},{"v":24,"t":"By faith Moses, when he had grown up, refused to be called the son of Pharaoh’s daughter,"},{"v":25,"t":"choosing rather to share ill treatment with God’s people than to enjoy the pleasures of sin for a time,"},{"v":26,"t":"considering the reproach of Christ greater riches than the treasures of Egypt; for he looked to the reward."},{"v":27,"t":"By faith he left Egypt, not fearing the wrath of the king; for he endured, as seeing him who is invisible."},{"v":28,"t":"By faith he kept the Passover and the sprinkling of the blood, that the destroyer of the firstborn should not touch them."},{"v":29,"t":"By faith they passed through the Red Sea as on dry land. When the Egyptians tried to do so, they were swallowed up."},{"v":30,"t":"By faith the walls of Jericho fell down after they had been encircled for seven days."},{"v":31,"t":"By faith Rahab the prostitute didn’t perish with those who were disobedient, having received the spies in peace."},{"v":32,"t":"What more shall I say? For the time would fail me if I told of Gideon, Barak, Samson, Jephthah, David, Samuel, and the prophets—"},{"v":33,"t":"who through faith subdued kingdoms, worked out righteousness, obtained promises, stopped the mouths of lions,"},{"v":34,"t":"quenched the power of fire, escaped the edge of the sword, from weakness were made strong, grew mighty in war, and caused foreign armies to flee."},{"v":35,"t":"Women received their dead by resurrection. Others were tortured, not accepting their deliverance, that they might obtain a better resurrection."},{"v":36,"t":"Others were tried by mocking and scourging, yes, moreover by bonds and imprisonment."},{"v":37,"t":"They were stoned. They were sawn apart. They were tempted. They were slain with the sword. They went around in sheep skins and in goat skins; being destitute, afflicted, ill-treated—"},{"v":38,"t":"of whom the world was not worthy—wandering in deserts, mountains, caves, and the holes of the earth."},{"v":39,"t":"These all, having been commended for their faith, didn’t receive the promise,"},{"v":40,"t":"God having provided some better thing concerning us, so that apart from us they should not be made perfect."}],"hr":[{"v":1,"t":"A vjera je već neko imanje onoga čemu se nadamo, uvjerenost u zbiljnosti kojih ne vidimo."},{"v":2,"t":"Zbog nje stari primiše svjedočanstvo."},{"v":3,"t":"Vjerom spoznajemo da su svjetovi uređeni riječju Božjom tako te ovo vidljivo ne posta od nečega pojavnoga."},{"v":4,"t":"Vjerom Abel prinese Bogu bolju žrtvu nego Kain. Po njoj primi svjedočanstvo da je pravedan - Bog nad njegovim darovima posvjedoči - po njoj i mrtav još govori."},{"v":5,"t":"Vjerom Henok bi prenesen da ne vidi smrti te iščeznu jer ga je prenio Bog. Doista, prije prijenosa primio je svjedočanstvo da omilje Bogu."},{"v":6,"t":"A bez vjere nemoguće je omiljeti Bogu jer tko mu pristupa, vjerovati mora da postoji i da je platac onima koji ga traže."},{"v":7,"t":"Vjerom Noa, upućen u ono što još ne bijaše vidljivo, predano sagradi korablju na spasenje svoga doma. Time osudi svijet i postade baštinikom vjerničke pravednosti."},{"v":8,"t":"Vjerom pozvan, Abraham posluša i zaputi se u kraj koji je imao primiti u baštinu, zaputi se ne znajući kamo ide."},{"v":9,"t":"Vjerom se kao pridošlica naseli u obećanoj zemlji kao u tuđini, prebivajući pod šatorima s Izakom i Jakovom, subaštinicima istog obećanja,"},{"v":10,"t":"jer iščekivaše onaj utemeljeni Grad kojemu je graditelj i tvorac Bog."},{"v":11,"t":"Vjerom i Sara unatoč svojoj dobi zadobi moć da začne jer vjernim smatraše Onoga koji joj dade obećanje."},{"v":12,"t":"Zato od jednoga, i to obamrla, nasta mnoštvo poput zvijezda na nebu i pijeska nebrojena na obali morskoj."},{"v":13,"t":"U vjeri svi su oni umrli, a da nisu zadobili obećanja, već su ih samo izdaleka vidjeli i pozdravili priznavši da su stranci i pridošlice na zemlji."},{"v":14,"t":"Doista, koji tako govore, jasno očituju da domovinu traže."},{"v":15,"t":"Dakako, da su mislili na onu iz koje su izišli, imali bi još prilike vratiti se u nju."},{"v":16,"t":"Ali sada oni čeznu za boljom, to jest nebeskom. Stoga se Bog ne stidi zvati se Bogom njihovim: ta pripravio im je Grad."},{"v":17,"t":"Vjerom Abraham, kušan, prikaza Izaka. Jedinca prikazivaše on koji je primio obećanje,"},{"v":18,"t":"kome bi rečeno: Po Izaku će ti se nazivati potomstvo! -"},{"v":19,"t":"uvjeren da Bog može i od mrtvih uskrisiti. Zato ga u predslici i ponovno zadobi."},{"v":20,"t":"Vjerom baš u pogledu budućnosti Izak blagoslovi Jakova i Ezava."},{"v":21,"t":"Vjerom Jakov, umirući, blagoslovi oba sina Josipova i duboko se prignu oslonjen na vrh svojega štapa."},{"v":22,"t":"Vjerom Josip na umoru napomenu ono o izlasku sinova Izraelovih i dade zapovijed o svojim kostima."},{"v":23,"t":"Vjerom su Mojsija netom rođena tri mjeseca krili njegovi roditelji jer vidješe da je djetešce lijepo i nisu se bojali kraljeve naredbe."},{"v":24,"t":"Vjerom Mojsije, već odrastao, odbi zvati se sinom kćeri faraonove."},{"v":25,"t":"Radije izabra biti zlostavljan zajedno s Božjim narodom, nego se časovito okoristiti grijehom."},{"v":26,"t":"Većim je bogatstvom od blaga egipatskih smatrao muku Kristovu jer je gledao na plaću."},{"v":27,"t":"Vjerom napusti Egipat, ne bojeći se bijesa kraljeva, postojan kao da Nevidljivoga vidi."},{"v":28,"t":"Vjerom je obavio pashu i škropljenje krvlju da Zatornik ne dotakne prvenaca Izraelovih."},{"v":29,"t":"Vjerom prođoše Crvenim morem kao po suhu, što i Egipćani pokušaše, ali se potopiše."},{"v":30,"t":"Vjerom zidine jerihonske padoše nakon sedmodnevnoga ophoda."},{"v":31,"t":"Vjerom Rahaba, bludnica, ne propade zajedno s nepokornicima jer s mirom primi uhode."},{"v":32,"t":"I što još da kažem? Ta ponestat će mi vremena, počnem li raspredati o Gideonu, Baraku, Samsonu, Jiftahu, Davidu, pa Samuelu i prorocima,"},{"v":33,"t":"koji su po vjeri osvojili kraljevstva, odjelotvorili pravednost, zadobili obećano, začepili ralje lavovima,"},{"v":34,"t":"pogasili žestinu ognja, umakli oštrici mača, oporavili se od slabosti, ojačali u boju, odbili navale tuđinaca."},{"v":35,"t":"Žene su po uskrsnuću ponovno zadobile svoje pokojne. Drugi pak, stavljeni na muke, ne prihvatiše oslobođenja da bi ih zapalo bolje uskrsnuće."},{"v":36,"t":"Drugi su opet iskusili izrugivanja i bičeve, pa i okove i tamnicu."},{"v":37,"t":"Kamenovani su, piljeni, poubijani oštricom mača, potucali se u runima, u kozjim kožusima, u oskudici, potlačeni, zlostavljani -"},{"v":38,"t":"svijet ih ne bijaše dostojan - vrludali po pustinjama, gorama, pećinama i pukotinama zemaljskim."},{"v":39,"t":"I svi oni po vjeri, istina, primiše svjedočanstvo, ali ne zadobiše obećano"},{"v":40,"t":"jer Bog je za nas predvidio nešto bolje da oni bez nas ne dođu do savršenstva."}]},"12":{"fa":[{"v":1,"t":"تادیب الهی بنابراین چونکه ما نیز چنین ابر شاهدان را گرداگرد خود داریم، هر بار گران وگناهی را که ما را سخت می‌پیچد دور بکنیم و باصبر در آن میدان که پیش روی ما مقرر شده است بدویم،"},{"v":2,"t":"و به سوی پیشوا و کامل کننده ایمان یعنی عیسی نگران باشیم که بجهت آن خوشی که پیش او موضوع بود، بی‌حرمتی را ناچیز شمرده، متحمل صلیب گردید و به‌دست راست تخت خدا نشسته است."},{"v":3,"t":"پس تفکر کنید در او که متحمل چنین مخالفتی بود که از گناهکاران به اوپدید آمد، مبادا در جانهای خود ضعف کرده، خسته شوید."},{"v":4,"t":"هنوز در جهاد با گناه تا به حدخون مقاومت نکرده‌اید،"},{"v":5,"t":"و نصیحتی را فراموش نموده‌اید که با شما چون با پسران مکالمه می‌کندکه «ای پسر من تادیب خداوند را خوار مشمار ووقتی که از او سرزنش یابی، خسته خاطر مشو."},{"v":6,"t":"زیرا هر‌که را خداوند دوست می‌دارد، توبیخ می‌فرماید و هر فرزند مقبول خود را به تازیانه می‌زند.»"},{"v":7,"t":"اگر متحمل تادیب شوید، خدا با شما مثل باپسران رفتار می‌نماید. زیرا کدام پسر است که پدرش او را تادیب نکند؟"},{"v":8,"t":"لکن اگر بی‌تادیب می‌باشید، که همه از آن بهره یافتند، پس شماحرام زادگانید نه پسران."},{"v":9,"t":"و دیگر پدران جسم خود را وقتی داشتیم که ما را تادیب می‌نمودند وایشان را احترام می‌نمودیم، آیا از طریق اولی پدرروحها را اطاعت نکنیم تا زنده شویم؟"},{"v":10,"t":"زیرا که ایشان اندک زمانی، موافق صوابدید خود ما راتادیب کردند، لکن او بجهت فایده تا شریک قدوسیت او گردیم."},{"v":11,"t":"لکن هر تادیب در حال، نه از خوشیها بلکه از دردها می‌نماید، اما در آخرمیوه عدالت سلامتی را برای آنانی که از آن ریاضت یافته‌اند بار می‌آورد."},{"v":12,"t":"لهذا دستهای افتاده و زانوهای سست شده را استوار نمایید،"},{"v":13,"t":"و برای پایهای خود راههای راست بسازید تاکسی‌که لنگ باشد، از طریق منحرف نشود، بلکه شفا یابد."},{"v":14,"t":"و در‌پی سلامتی با همه بکوشید و تقدسی که بغیر از آن هیچ‌کس خداوند را نخواهد دید."},{"v":15,"t":"و مترصد باشید مبادا کسی از فیض خدامحروم شود و ریشه مرارت نمو کرده، اضطراب بار آورد و جمعی از آن آلوده گردند."},{"v":16,"t":"مباداشخصی زانی یا بی‌مبالات پیدا شود، مانند عیسوکه برای طعامی نخستزادگی خود را بفروخت."},{"v":17,"t":"زیرا می‌دانید که بعد از آن نیز وقتی که خواست وارث برکت شود مردود گردید (زیرا که جای توبه پیدا ننمود) با آنکه با اشکها در جستجوی آن بکوشید."},{"v":18,"t":"زیرا تقرب نجسته‌اید به کوهی که می‌توان لمس کرد و به آتش افروخته و نه به تاریکی وظلمت و باد سخت،"},{"v":19,"t":"و نه به آواز کرنا و صدای کلامی که شنوندگان، التماس کردند که آن کلام، دیگر بدیشان گفته نشود."},{"v":20,"t":"زیرا که متحمل آن قدغن نتوانستند شد که اگر حیوانی نیز کوه رالمس کند، سنگسار یا به نیزه زده شود."},{"v":21,"t":"و آن رویت بحدی ترسناک بود که موسی گفت: «بغایت ترسان و لرزانم.»"},{"v":22,"t":"بلکه تقرب جسته ایدبه جبل صهیون و شهر خدای حی یعنی اورشلیم سماوی و به جنود بی‌شماره از محفل فرشتگان"},{"v":23,"t":"و کلیسای نخستزادگانی که در آسمان مکتوبندو به خدای داور جمیع و به ارواح عادلان مکمل"},{"v":24,"t":"و به عیسی متوسط عهد جدید و به خون پاشیده شده که متکلم است به‌معنی نیکوتر ازخون هابیل."},{"v":25,"t":"زنهار از آنکه سخن می‌گوید رو مگردانیدزیرا اگر آنانی که از آنکه بر زمین سخن گفت روگردانیدند، نجات نیافتند، پس ما چگونه نجات خواهیم یافت اگر از او که از آسمان سخن می‌گوید روگردانیم؟"},{"v":26,"t":"که آواز او در آن وقت زمین را جنبایند، لکن الان وعده داده است که «یک مرتبه دیگر نه فقط زمین بلکه آسمان را نیزخواهم جنبانید.»"},{"v":27,"t":"و این قول او یک مرتبه دیگراشاره است از تبدیل چیزهایی که جنبانیده می‌شود، مثل آنهایی که ساخته شد، تا آنهایی که جنبانیده نمی شود باقی ماند."},{"v":28,"t":"پس چون ملکوتی را که نمی توان جنبانیدمی یابیم، شکر به‌جا بیاوریم تا به خشوع و تقواخدا را عبادت پسندیده نماییم."},{"v":29,"t":"زیرا خدای ماآتش فروبرنده است."}],"en":[{"v":1,"t":"Therefore let’s also, seeing we are surrounded by so great a cloud of witnesses, lay aside every weight and the sin which so easily entangles us, and let’s run with perseverance the race that is set before us,"},{"v":2,"t":"looking to Jesus, the author and perfecter of faith, who for the joy that was set before him endured the cross, despising its shame, and has sat down at the right hand of the throne of God."},{"v":3,"t":"For consider him who has endured such contradiction of sinners against himself, that you don’t grow weary, fainting in your souls."},{"v":4,"t":"You have not yet resisted to blood, striving against sin."},{"v":5,"t":"You have forgotten the exhortation which reasons with you as with children, “My son, don’t take lightly the chastening of the Lord, nor faint when you are reproved by him;"},{"v":6,"t":"for whom the Lord loves, he disciplines, and chastises every son whom he receives.”"},{"v":7,"t":"It is for discipline that you endure. God deals with you as with children, for what son is there whom his father doesn’t discipline?"},{"v":8,"t":"But if you are without discipline, of which all have been made partakers, then you are illegitimate, and not children."},{"v":9,"t":"Furthermore, we had the fathers of our flesh to chasten us, and we paid them respect. Shall we not much rather be in subjection to the Father of spirits and live?"},{"v":10,"t":"For they indeed for a few days disciplined us as seemed good to them, but he for our profit, that we may be partakers of his holiness."},{"v":11,"t":"All chastening seems for the present to be not joyous but grievous; yet afterward it yields the peaceful fruit of righteousness to those who have been trained by it."},{"v":12,"t":"Therefore lift up the hands that hang down and the feeble knees,"},{"v":13,"t":"and make straight paths for your feet, so what is lame may not be dislocated, but rather be healed."},{"v":14,"t":"Follow after peace with all men, and the sanctification without which no man will see the Lord,"},{"v":15,"t":"looking carefully lest there be any man who falls short of the grace of God, lest any root of bitterness springing up trouble you and many be defiled by it,"},{"v":16,"t":"lest there be any sexually immoral person or profane person, like Esau, who sold his birthright for one meal."},{"v":17,"t":"For you know that even when he afterward desired to inherit the blessing, he was rejected, for he found no place for a change of mind though he sought it diligently with tears."},{"v":18,"t":"For you have not come to a mountain that might be touched and that burned with fire, and to blackness, darkness, storm,"},{"v":19,"t":"the sound of a trumpet, and the voice of words; which those who heard it begged that not one more word should be spoken to them,"},{"v":20,"t":"for they could not stand that which was commanded, “If even an animal touches the mountain, it shall be stoned”."},{"v":21,"t":"So fearful was the appearance that Moses said, “I am terrified and trembling.”"},{"v":22,"t":"But you have come to Mount Zion and to the city of the living God, the heavenly Jerusalem, and to innumerable multitudes of angels,"},{"v":23,"t":"to the festal gathering and assembly of the firstborn who are enrolled in heaven, to God the Judge of all, to the spirits of just men made perfect,"},{"v":24,"t":"to Jesus, the mediator of a new covenant, and to the blood of sprinkling that speaks better than that of Abel."},{"v":25,"t":"See that you don’t refuse him who speaks. For if they didn’t escape when they refused him who warned on the earth, how much more will we not escape who turn away from him who warns from heaven,"},{"v":26,"t":"whose voice shook the earth then, but now he has promised, saying, “Yet once more I will shake not only the earth, but also the heavens.”"},{"v":27,"t":"This phrase, “Yet once more” signifies the removing of those things that are shaken, as of things that have been made, that those things which are not shaken may remain."},{"v":28,"t":"Therefore, receiving a Kingdom that can’t be shaken, let’s have grace, through which we serve God acceptably, with reverence and awe,"},{"v":29,"t":"for our God is a consuming fire."}],"hr":[{"v":1,"t":"Zato i mi, okruženi tolikim oblakom svjedoka, odložimo svaki teret i grijeh koji nas sapinje te postojano trčimo u borbu koja je pred nama!"},{"v":2,"t":"Uprimo pogled u Početnika i Dovršitelja vjere, Isusa, koji umjesto radosti što je stajala pred njim podnese križ, prezrevši sramotu te sjedi zdesna prijestolja Božjega."},{"v":3,"t":"Doista pomno promotrite njega, koji podnese toliko protivljenje grešnika protiv sebe, da - premoreni - ne klonete duhom."},{"v":4,"t":"Ta još se do krvi ne oduprijeste u borbi protiv grijeha."},{"v":5,"t":"Pa zar ste zaboravili opomenu koja vam je kao sinovima upravljena: Sine moj, ne omalovažavaj stege Gospodnje i ne kloni kad te on ukori."},{"v":6,"t":"Jer koga Gospodin ljubi, onoga i stegom odgaja, šiba sina koga voli."},{"v":7,"t":"Poradi vašega odgajanja trpite. Bog s vama postupa kao sa sinovima: a ima li koji sin kojega otac stegom ne odgaja?"},{"v":8,"t":"Pa ako niste pod stegom, na kojoj su svi imali udjela, onda ste kopilad, a ne djeca."},{"v":9,"t":"Zatim, tjelesne smo oce imali odgojiteljima i poštovali ih. Pa nećemo li se kudikamo više podlagati Ocu duhova te živjeti?"},{"v":10,"t":"Oni su nas doista nešto malo dana stegom odgajali kako se njima činilo, a On - nama na korist, da postanemo sudionici njegove svetosti."},{"v":11,"t":"Isprva se doduše čini da nijedno odgajanje nije radost, nego žalost, ali onima koji su njime uvježbani poslije donosi mironosni plod pravednosti."},{"v":12,"t":"Zato uspravite ruke klonule i koljena klecava,"},{"v":13,"t":"poravnite staze za noge svoje da se hromo ne iščaši, nego, štoviše, da ozdravi."},{"v":14,"t":"Nastojte oko mira sa svima! I oko posvećenja bez kojega nitko neće vidjeti Gospodina!"},{"v":15,"t":"Pripazite da se tko ne sustegne od milosti Božje, da kakav gorki korijen ne proklija pa ne unese zabunu i ne zarazi mnoge,"},{"v":16,"t":"da tko ne postane bludnik ili svetogrdnik kao Ezav, koji za jedan jedini obrok proda svoje prvorodstvo."},{"v":17,"t":"Ta znate da je i poslije, kad je htio baštiniti blagoslov, odbačen jer nije našao mogućnosti promjene premda ju je sa suzama tražio."},{"v":18,"t":"Jer niste pristupili opipljivoj gori i usplamtjelu ognju, ni mraku, tami i vihoru,"},{"v":19,"t":"ni ječanju trublje i tutnjavi riječi. - Koji su je slušali, zamoliše da im se više ne govori"},{"v":20,"t":"jer nisu podnosili naredbe: Ako se ma i živinče dotakne brda, neka se kamenuje!"},{"v":21,"t":"I prizor bijaše tako strašan da Mojsije reče: “Strah me je i dršćem!” -"},{"v":22,"t":"Nego, vi ste pristupili gori Sionu i gradu Boga živoga, Jeruzalemu nebeskom, nebrojenim tisućama anđela, svečanom skupu,"},{"v":23,"t":"Crkvi prvorođenaca zapisanih na nebu, Bogu, sucu sviju, dusima savršenih pravednika"},{"v":24,"t":"i Posredniku novog Saveza - Isusu - i krvi škropljeničkoj što snažnije govori od Abelove."},{"v":25,"t":"Pazite da ne odbijete Onoga koji vam govori! Jer ako ne umakoše oni što su odbili onoga koji je na zemlji davao upute, kudikamo ćemo manje mi ako se okrenemo od Onoga koji ih daje s nebesa."},{"v":26,"t":"Njegov glas tada zemlju uzdrma, sada pak obećava: Još jednom ja ću potresti ne samo zemlju nego i nebo."},{"v":27,"t":"Ono “još jednom” pokazuje da će, kao stvoreno, uminuti ono uzdrmano da ostane ono neuzdrmljivo."},{"v":28,"t":"Zato jer smo primili kraljevstvo neuzdrmljivo, iskazujmo zahvalnost iz koje služimo Bogu kako je njemu milo, s predanjem i strahopoštovanjem."},{"v":29,"t":"Jer Bog je naš oganj što proždire."}]},"13":{"fa":[{"v":1,"t":"محبت برادرانه برقرار باشد؛"},{"v":2,"t":"و ازغریب‌نوازی غافل مشوید زیرا که به آن بعضی نادانسته فرشتگان را ضیافت کردند."},{"v":3,"t":"اسیران را بخاطر آرید مثل همزندان ایشان، ومظلومان را چون شما نیز در جسم هستید."},{"v":4,"t":"نکاح به هر وجه محترم باشد و بسترش غیرنجس زیرا که فاسقان و زانیان را خدا داوری خواهد فرمود."},{"v":5,"t":"سیرت شما از محبت نقره خالی باشد و به آنچه دارید قناعت کنید زیرا که او گفته است: «تو را هرگز رها نکنم و تو را ترک نخواهم نمود.»"},{"v":6,"t":"بنابراین ما با دلیری تمام می‌گوییم: «خداوند مددکننده من است و ترسان نخواهم بود. انسان به من چه می‌کند؟»"},{"v":7,"t":"مرشدان خود را که کلام خدا را به شما بیان کردند بخاطر دارید و انجام سیرت ایشان راملاحظه کرده، به ایمان ایشان اقتدا نمایید."},{"v":8,"t":"عیسی مسیح دیروز و امروز و تا ابدالاباد همان است."},{"v":9,"t":"از تعلیمهای مختلف و غریب از جا برده مشوید، زیرا بهتر آن است که دل شما به فیض استوار شود و نه به خوراکهایی که آنانی که در آنهاسلوک نمودند، فایده نیافتند."},{"v":10,"t":"مذبحی داریم که خدمت گذاران آن خیمه، اجازت ندارند که از آن بخورند."},{"v":11,"t":"زیرا که جسدهای آن حیواناتی که رئیس کهنه خون آنهارا به قدس‌الاقداس برای گناه می‌برد، بیرون ازلشکرگاه سوخته می‌شود."},{"v":12,"t":"بنابراین، عیسی نیزتا قوم را به خون خود تقدیس نماید، بیرون دروازه عذاب کشید."},{"v":13,"t":"لهذا عار او را برگرفته، بیرون از لشکرگاه به سوی او برویم."},{"v":14,"t":"زانرو که در اینجا شهری باقی نداریم بلکه آینده را طالب هستیم."},{"v":15,"t":"پس بوسیله او قربانی تسبیح را به خدابگذرانیم، یعنی ثمره لبهایی را که به اسم او معترف باشند."},{"v":16,"t":"لکن از نیکوکاری و خیرات غافل مشوید، زیرا خدا به همین قربانی‌ها راضی است."},{"v":17,"t":"مرشدان خود را اطاعت و انقیاد نمایید زیراکه ایشان پاسبانی جانهای شما را می‌کنند، چونکه حساب خواهند داد تا آن را به خوشی نه به ناله به‌جا آورند، زیرا که این شما را مفید نیست."},{"v":18,"t":"برای ما دعا کنید زیرا ما را یقین است که ضمیر خالص داریم و می‌خواهیم در هر امر رفتارنیکو نماییم."},{"v":19,"t":"و بیشتر التماس دارم که چنین کنید تا زودتر به نزد شما باز آورده شوم."},{"v":20,"t":"پس خدای سلامتی که شبان اعظم گوسفندان یعنی خداوند ما عیسی را به خون عهدابدی از مردگان برخیزانید،"},{"v":21,"t":"شما را در هر عمل نیکو کامل گرداناد تا اراده او را به‌جا آورید وآنچه منظور نظر او باشد، در شما بعمل آوردبوساطت عیسی مسیح که او را تا ابدالاباد جلال باد. آمین."},{"v":22,"t":"لکن‌ای برادران از شما التماس دارم که این کلام نصیحت‌آمیز را متحمل شوید زیرامختصری نیز به شما نوشته‌ام."},{"v":23,"t":"بدانید که برادرما تیموتاوس رهایی یافته است و اگر زود آید، به اتفاق او شما را ملاقات خواهم نمود."},{"v":24,"t":"همه مرشدان خود و جمیع مقدسین راسلام برسانید؛ و آنانی که از ایتالیا هستند، به شماسلام می‌رسانند."},{"v":25,"t":"همگی شما را فیض باد. آمین."}],"en":[{"v":1,"t":"Let brotherly love continue."},{"v":2,"t":"Don’t forget to show hospitality to strangers, for in doing so, some have entertained angels without knowing it."},{"v":3,"t":"Remember those who are in bonds, as bound with them, and those who are ill-treated, since you are also in the body."},{"v":4,"t":"Let marriage be held in honor among all, and let the bed be undefiled; but God will judge the sexually immoral and adulterers."},{"v":5,"t":"Be free from the love of money, content with such things as you have, for he has said, “I will in no way leave you, neither will I in any way forsake you.”"},{"v":6,"t":"So that with good courage we say, “The Lord is my helper. I will not fear. What can man do to me?”"},{"v":7,"t":"Remember your leaders, men who spoke to you the word of God, and considering the results of their conduct, imitate their faith."},{"v":8,"t":"Jesus Christ is the same yesterday, today, and forever."},{"v":9,"t":"Don’t be carried away by various and strange teachings, for it is good that the heart be established by grace, not by foods, through which those who were so occupied were not benefited."},{"v":10,"t":"We have an altar from which those who serve the holy tabernacle have no right to eat."},{"v":11,"t":"For the bodies of those animals, whose blood is brought into the holy place by the high priest as an offering for sin, are burned outside of the camp."},{"v":12,"t":"Therefore Jesus also, that he might sanctify the people through his own blood, suffered outside of the gate."},{"v":13,"t":"Let’s therefore go out to him outside of the camp, bearing his reproach."},{"v":14,"t":"For we don’t have here an enduring city, but we seek that which is to come."},{"v":15,"t":"Through him, then, let’s offer up a sacrifice of praise to God continually, that is, the fruit of lips which proclaim allegiance to his name."},{"v":16,"t":"But don’t forget to be doing good and sharing, for with such sacrifices God is well pleased."},{"v":17,"t":"Obey your leaders and submit to them, for they watch on behalf of your souls, as those who will give account, that they may do this with joy and not with groaning, for that would be unprofitable for you."},{"v":18,"t":"Pray for us, for we are persuaded that we have a good conscience, desiring to live honorably in all things."},{"v":19,"t":"I strongly urge you to do this, that I may be restored to you sooner."},{"v":20,"t":"Now may the God of peace, who brought again from the dead the great shepherd of the sheep with the blood of an eternal covenant, our Lord Jesus,"},{"v":21,"t":"make you complete in every good work to do his will, working in you that which is well pleasing in his sight, through Jesus Christ, to whom be the glory forever and ever. Amen."},{"v":22,"t":"But I exhort you, brothers, endure the word of exhortation, for I have written to you in few words."},{"v":23,"t":"Know that our brother Timothy has been freed, with whom, if he comes shortly, I will see you."},{"v":24,"t":"Greet all of your leaders and all the saints. The Italians greet you."},{"v":25,"t":"Grace be with you all. Amen."}],"hr":[{"v":1,"t":"Bratoljublje neka je trajno!"},{"v":2,"t":"Gostoljublja ne zaboravljajte: njime neki, i ne znajući, ugostiše anđele!"},{"v":3,"t":"Sjećajte se uznika kao suuznici; zlostavljanih - ta i sami ste u tijelu!"},{"v":4,"t":"Ženidba neka bude u časti u sviju i postelja neokaljana! Jer bludnicima će i preljubnicima suditi Bog."},{"v":5,"t":"U življenju ne budite srebroljupci, zadovoljni onim što imate! Ta on je rekao: Ne, neću te zapustiti i neću te ostaviti."},{"v":6,"t":"Zato možemo pouzdano reći: Gospodin mi je pomoćnik, ja ne strahujem: što mi tko može?"},{"v":7,"t":"Spominjite se svojih glavara koji su vam nevješćivali riječ Božju: promatrajući kraj njihova života, nasljedujte njihovu vjeru."},{"v":8,"t":"Isus Krist jučer i danas isti je - i uvijeke."},{"v":9,"t":"Ne dajte se zanijeti različitim tuđim naucima! Jer bolje je srce utvrđivati milošću nego jelima, koja nisu koristila onima što su ih obdržavali."},{"v":10,"t":"Imamo žrtvenik s kojega nemaju pravo jesti služitelji Šatora."},{"v":11,"t":"Jer tijela životinja, kojih krv veliki svećenik unosi za grijeh u Svetinju, spaljuju se izvan tabora."},{"v":12,"t":"Zato i Isus, da bi vlastitom krvlju posvetio narod, trpio je izvan vrata."},{"v":13,"t":"Stoga iziđimo k njemu izvan tabora noseći njegovu muku"},{"v":14,"t":"jer nemamo ovdje trajna grada, nego onaj budući tražimo."},{"v":15,"t":"Po njemu dakle neprestano prinosimo Bogu žrtvu hvalbenu, to jest plod usana što ispovijedaju ime njegovo."},{"v":16,"t":"Dobrotvornosti i zajedništva ne zaboravljajte jer takve su žrtve mile Bogu!"},{"v":17,"t":"Poslušni budite svojim glavarima i podložni jer oni bdiju nad vašim dušama kao oni koji će polagati račun; neka to čine s radošću, a ne uzdišući jer vam to ne bi bilo korisno."},{"v":18,"t":"Molite za nas! Uvjereni smo doista da imamo dobru savjest i u svemu se želimo dobro ponašati."},{"v":19,"t":"Usrdnije vas pak molim: učinite to kako bih vam se što brže vratio."},{"v":20,"t":"A Bog mira, koji po krvi vječnoga Saveza od mrtvih izvede velikoga Pastira ovaca, Gospodina našega Isusa,"},{"v":21,"t":"osposobio vas za svako dobro djelo da vršite volju njegovu, činio u nama što je njemu milo, po Isusu Kristu, komu slava u vijeke vjekova. Amen."},{"v":22,"t":"Molim vas, braćo, podnesite ovu riječ ohrabrenja: ta samo vam ukratko napisah!"},{"v":23,"t":"Znajte: naš je brat Timotej oslobođen. Ako uskoro stigne, s njime ću vas pohoditi."},{"v":24,"t":"Pozdravite sve svoje glavare i sve svete! Pozdravljaju vas ovi iz Italije."},{"v":25,"t":"Milost sa svima vama!"}]}},"JAS":{"1":{"fa":[{"v":1,"t":"یعقوب که غلام خدا و عیسی مسیح خداوند است، به دوازده سبط که پراکنده هستند. خوش باشید."},{"v":2,"t":"‌ای برادران من، وقتی که در تجربه های گوناگون مبتلا شوید، کمال خوشی دانید."},{"v":3,"t":"چونکه می‌دانید که امتحان ایمان شما صبر راپیدا می‌کند."},{"v":4,"t":"لکن صبر را عمل تام خود باشد تاکامل و تمام شوید و محتاج هیچ‌چیز نباشید."},{"v":5,"t":"واگر از شما کسی محتاج به حکمت باشد، سوال بکند از خدایی که هر کس را به سخاوت عطامی کند و ملامت نمی نماید و به او داده خواهدشد."},{"v":6,"t":"لکن به ایمان سوال بکند و هرگز شک نکندزیرا هرکه شک کند، مانند موج دریاست که از بادرانده و متلاطم می‌شود."},{"v":7,"t":"زیرا چنین شخص گمان نبرد که از خداوند چیزی خواهد یافت."},{"v":8,"t":"مرد دودل در تمام رفتار خود ناپایدار است."},{"v":9,"t":"لکن برادر مسکین به‌سرافرازی خود فخربنماید،"},{"v":10,"t":"و دولتمند از مسکنت خود، زیرا مثل گل علف در گذر است."},{"v":11,"t":"از آنرو که آفتاب باگرمی طلوع کرده، علف را خشکانید و گلش به زیر افتاده، حسن صورتش زایل شد. به همینطورشخص دولتمند نیز در راههای خود، پژمرده خواهد گردید."},{"v":12,"t":"خوشابحال کسی‌که متحمل تجربه شود، زیرا که چون آزموده شد، آن تاج حیاتی را که خداوند به محبان خود وعده فرموده است خواهد یافت."},{"v":13,"t":"هیچ‌کس چون در تجربه افتد، نگوید: «خدا مرا تجربه می‌کند»، زیرا خدا هرگزاز بدیها تجربه نمی شود و او هیچ‌کس را تجربه نمی کند."},{"v":14,"t":"لکن هرکس در تجربه می‌افتد وقتی که شهوت وی او را می‌کشد و فریفته می‌سازد."},{"v":15,"t":"پس شهوت آبستن شده، گناه را می‌زاید و گناه به انجام رسیده، موت را تولید می‌کند."},{"v":16,"t":"‌ای برادران عزیز من، گمراه مشوید!"},{"v":17,"t":"هر بخشندگی نیکو و هر بخشش کامل از بالا است و نازل می‌شود از پدر نورها که نزد او هیچ تبدیل و سایه گردش نیست."},{"v":18,"t":"او محض اراده خود ما رابوسیله کلمه حق تولید نمود تا ما چون نوبرمخلوقات او باشیم."},{"v":19,"t":"بنابراین، ای برادران عزیز من، هرکس درشنیدن تند و در گفتن آهسته و در خشم سست باشد."},{"v":20,"t":"زیرا خشم انسان عدالت خدا را به عمل نمی آورد."},{"v":21,"t":"پس هر نجاست و افزونی شر را دورکنید و با فروتنی، کلام کاشته شده را بپذیرید که قادر است که جانهای شما را نجات‌بخشد."},{"v":22,"t":"لکن کنندگان کلام باشید نه فقط شنوندگان که خود را فریب می‌دهند."},{"v":23,"t":"زیرا اگر کسی کلام را بشنود و عمل نکند، شخصی را ماند که صورت طبیعی خود را در آینه می‌نگرد."},{"v":24,"t":"زیرا خود رانگریست و رفت و فور فراموش کرد که چطورشخصی بود."},{"v":25,"t":"لکن کسی‌که بر شریعت کامل آزادی چشم دوخت و در آن ثابت ماند، او چون شنونده فراموشکار نمی باشد، بلکه کننده عمل پس او در عمل خود مبارک خواهد بود."},{"v":26,"t":"اگرکسی از شما گمان برد که پرستنده خدا است وعنان زبان خود را نکشد بلکه دل خود را فریب دهد، پرستش او باطل است."},{"v":27,"t":"پرستش صاف وبی عیب نزد خدا و پدر این است که یتیمان وبیوه‌زنان را در مصیبت ایشان تفقد کنند و خود رااز آلایش دنیا نگاه دارند."}],"en":[{"v":1,"t":"James, a servant of God and of the Lord Jesus Christ, to the twelve tribes which are in the Dispersion: Greetings."},{"v":2,"t":"Count it all joy, my brothers, when you fall into various temptations,"},{"v":3,"t":"knowing that the testing of your faith produces endurance."},{"v":4,"t":"Let endurance have its perfect work, that you may be perfect and complete, lacking in nothing."},{"v":5,"t":"But if any of you lacks wisdom, let him ask of God, who gives to all liberally and without reproach, and it will be given to him."},{"v":6,"t":"But let him ask in faith, without any doubting, for he who doubts is like a wave of the sea, driven by the wind and tossed."},{"v":7,"t":"For that man shouldn’t think that he will receive anything from the Lord."},{"v":8,"t":"He is a double-minded man, unstable in all his ways."},{"v":9,"t":"Let the brother in humble circumstances glory in his high position;"},{"v":10,"t":"and the rich, in that he is made humble, because like the flower in the grass, he will pass away."},{"v":11,"t":"For the sun arises with the scorching wind and withers the grass; and the flower in it falls, and the beauty of its appearance perishes. So the rich man will also fade away in his pursuits."},{"v":12,"t":"Blessed is a person who endures temptation, for when he has been approved, he will receive the crown of life which the Lord promised to those who love him."},{"v":13,"t":"Let no man say when he is tempted, “I am tempted by God,” for God can’t be tempted by evil, and he himself tempts no one."},{"v":14,"t":"But each one is tempted when he is drawn away by his own lust and enticed."},{"v":15,"t":"Then the lust, when it has conceived, bears sin. The sin, when it is full grown, produces death."},{"v":16,"t":"Don’t be deceived, my beloved brothers."},{"v":17,"t":"Every good gift and every perfect gift is from above, coming down from the Father of lights, with whom can be no variation nor turning shadow."},{"v":18,"t":"Of his own will he gave birth to us by the word of truth, that we should be a kind of first fruits of his creatures."},{"v":19,"t":"So, then, my beloved brothers, let every man be swift to hear, slow to speak, and slow to anger;"},{"v":20,"t":"for the anger of man doesn’t produce the righteousness of God."},{"v":21,"t":"Therefore, putting away all filthiness and overflowing of wickedness, receive with humility the implanted word, which is able to save your souls."},{"v":22,"t":"But be doers of the word, and not only hearers, deluding your own selves."},{"v":23,"t":"For if anyone is a hearer of the word and not a doer, he is like a man looking at his natural face in a mirror;"},{"v":24,"t":"for he sees himself, and goes away, and immediately forgets what kind of man he was."},{"v":25,"t":"But he who looks into the perfect law of freedom and continues, not being a hearer who forgets but a doer of the work, this man will be blessed in what he does."},{"v":26,"t":"If anyone among you thinks himself to be religious while he doesn’t bridle his tongue, but deceives his heart, this man’s religion is worthless."},{"v":27,"t":"Pure religion and undefiled before our God and Father is this: to visit the fatherless and widows in their affliction, and to keep oneself unstained by the world."}],"hr":[{"v":1,"t":"Jakov, sluga Boga i Gospodina Isusa Krista: dvanaestorma plemena Raseljeništva pozdrav."},{"v":2,"t":"Pravom radošću smatrajte, braćo moja, kad upadnete u razne kušnje"},{"v":3,"t":"znajući da prokušanost vaše vjere rađa postojanošću."},{"v":4,"t":"Ali neka postojanost bude na djelu savršena da budete savršeni i potpuni, bez ikakva nedostataka."},{"v":5,"t":"Nedostaje li komu od vas mudrosti, neka ište od Boga, koji svima daje rado i bez negodovanja, i dat će mu se."},{"v":6,"t":"Ali neka ište s vjerom, bez ikakva kolebanja. Jer kolebljivac je sličan morskom valovlju, uzburkanu i gonjenu."},{"v":7,"t":"Neka takav ne misli da će primiti što od Gospodina -"},{"v":8,"t":"čovjek duše dvoumne, nepostojan na svim putovima svojim."},{"v":9,"t":"Neka se brat niska soja ponosi svojim uzvišenjem,"},{"v":10,"t":"a bogataš svojim poniženjem. Ta proći će kao cvijet trave:"},{"v":11,"t":"sunce ogranu žarko te usahnu trava i cvijet njezin uvenu; dražest mu lica propade. Tako će i bogataš na stazama svojim usahnuti."},{"v":12,"t":"Blago čovjeku koji trpi kušnju: prokušan, primit će vijenac života koji je Gospodin obećao onima što ga ljube."},{"v":13,"t":"Neka nitko u napasti ne rekne: “Bog me napastuje.” Ta Bog ne može biti napastovan na zlo, i ne napastuje nikoga."},{"v":14,"t":"Nego svakoga napastuje njegova požuda koja ga privlači i mami."},{"v":15,"t":"Požuda zatim, zatrudnjevši, rađa grijehom, a grijeh izvršen rađa smrću."},{"v":16,"t":"Ne varajte se, braćo moja ljubljena!"},{"v":17,"t":"Svaki dobar dar, svaki savršen poklon odozgor je, silazi od Oca svjetlila u kome nema promjene ni sjene od mijene."},{"v":18,"t":"Po svom naumu on nas porodi riječju Istine da budemo prvina neka njegovih stvorova."},{"v":19,"t":"Znajte, braćo moja ljubljena! Svatko neka bude brz da sluša, spor da govori, spor na srdžbu."},{"v":20,"t":"Jer srdžba čovjekova ne čini pravde Božje."},{"v":21,"t":"Zato odložite svaku prljavštinu i preostalu zloću i sa svom krotkošću primite usađenu riječ koja ima moć spasiti duše vaše."},{"v":22,"t":"Budite vršitelji riječi, a ne samo slušatelji, zavaravajući sami sebe."},{"v":23,"t":"Jer ako je tko slušatelj riječi, a ne i izvršitelj, sličan je čovjeku koji motri svoje rođeno lice u zrcalu:"},{"v":24,"t":"promotri se, ode i odmah zaboravi kakav bijaše."},{"v":25,"t":"A koji se oglÄedÄa u savršenom zakonu slobode i uza nj prione, ne kao zaboravan slušatelj nego djelotvoran izvršitelj, blažen će biti u svem djelovanju svome."},{"v":26,"t":"Smatra li se tko bogoljubnim, a ne obuzdava svoga jezika, nego zavarava srce svoje, isprazna je njegova bogoljubnost."},{"v":27,"t":"Bogoljubnost čista i neokaljana jest: zauzimati se za sirote i udovice u njihovoj nevolji, čuvati se neokaljanim od ovoga svijeta."}]},"2":{"fa":[{"v":1,"t":"ای برادران من، ایمان خداوند ما عیسی مسیح، رب الجلال را با ظاهربینی مدارید."},{"v":2,"t":"زیرا اگر به کنیسه شما شخصی با انگشتری زرین و لباس نفیس داخل شود و فقیری نیز باپوشاک ناپاک درآید،"},{"v":3,"t":"و به صاحب لباس فاخرمتوجه شده، گویید: «اینجا نیکو بنشین» و به فقیرگویید: «تو در آنجا بایست یا زیر پای انداز من بنشین»،"},{"v":4,"t":"آیا در خود متردد نیستید و داوران خیالات فاسد نشده‌اید؟"},{"v":5,"t":"‌ای برادران عزیز، گوش دهید. آیا خدا فقیران این جهان را برنگزیده است تا دولتمند در ایمان و وارث آن ملکوتی که به محبان خود وعده فرموده است بشوند؟"},{"v":6,"t":"لکن شما فقیر را حقیر شمرده‌اید. آیا دولتمندان برشما ستم نمی کنند و شما را در محکمه هانمی کشند؟"},{"v":7,"t":"آیا ایشان به آن نام نیکو که بر شما نهاده شده است کفر نمی گویند؟"},{"v":8,"t":"اما اگر آن شریعت ملوکانه را برحسب کتاب به‌جا آورید یعنی «همسایه خود را مثل نفس خود محبت نما» نیکو می‌کنید."},{"v":9,"t":"لکن اگرظاهربینی کنید، گناه می‌کنید و شریعت شما را به خطاکاری ملزم می‌سازد."},{"v":10,"t":"زیرا هرکه تمام شریعت را نگاه دارد و در یک جزو بلغزد، ملزم همه می‌باشد."},{"v":11,"t":"زیرا او که گفت: «زنا مکن»، نیزگفت: «قتل مکن». پس هرچند زنا نکنی، اگر قتل کردی، از شریعت تجاوز نمودی."},{"v":12,"t":"همچنین سخن گویید و عمل نمایید مانند کسانی که برایشان داوری به شریعت آزادی خواهد شد."},{"v":13,"t":"زیرا آن داوری بی‌رحم خواهد بود برکسی‌که رحم نکرده است و رحم بر داوری مفتخرمی شود."},{"v":14,"t":"‌ای برادران من، چه سود دارد اگر کسی گوید: «ایمان دارم» وقتی که عمل ندارد؟ آیاایمان می‌تواند او را نجات‌بخشد؟"},{"v":15,"t":"پس اگربرادری یا خواهری برهنه و محتاج خوراک روزینه باشد،"},{"v":16,"t":"و کسی از شما بدیشان گوید: «به سلامتی بروید و گرم و سیر شوید»، لیکن مایحتاج بدن را بدیشان ندهد، چه نفع دارد؟"},{"v":17,"t":"همچنین ایمان نیز اگر اعمال ندارد، در خودمرده است."},{"v":18,"t":"بلکه کسی خواهد گفت: «تو ایمان داری و من اعمال دارم. ایمان خود را بدون اعمال به من بنما و من ایمان خود را از اعمال خود به توخواهم نمود.»"},{"v":19,"t":"تو ایمان داری که خدا واحداست؟ نیکو می‌کنی! شیاطین نیز ایمان دارند و می لرزند!"},{"v":20,"t":"و لیکن‌ای مرد باطل، آیا می‌خواهی دانست که ایمان بدون اعمال، باطل است؟"},{"v":21,"t":"آیا پدر ما ابراهیم به اعمال، عادل شمرده نشد وقتی که پسر خود اسحاق را به قربانگاه گذرانید؟"},{"v":22,"t":"می‌بینی که ایمان با اعمال او عمل کرد و ایمان از اعمال، کامل گردید."},{"v":23,"t":"و آن نوشته تمام گشت که می‌گوید: «ابراهیم به خداایمان آورد و برای او به عدالت محسوب گردید»، و دوست خدا نامیده شد."},{"v":24,"t":"پس می‌بینید که انسان از اعمال عادل شمرده می‌شود، نه از ایمان تنها."},{"v":25,"t":"و همچنین آیا راحاب فاحشه نیز ازاعمال عادل شمرده نشد وقتی که قاصدان راپذیرفته، به راهی دیگر روانه نمود؟"},{"v":26,"t":"زیراچنانکه بدن بدون روح مرده است، همچنین ایمان بدون اعمال نیز مرده است."}],"en":[{"v":1,"t":"My brothers, don’t hold the faith of our glorious Lord Jesus Christ with partiality."},{"v":2,"t":"For if a man with a gold ring, in fine clothing, comes into your synagogue, and a poor man in filthy clothing also comes in,"},{"v":3,"t":"and you pay special attention to him who wears the fine clothing and say, “Sit here in a good place;” and you tell the poor man, “Stand there,” or “Sit by my footstool”"},{"v":4,"t":"haven’t you shown partiality among yourselves, and become judges with evil thoughts?"},{"v":5,"t":"Listen, my beloved brothers. Didn’t God choose those who are poor in this world to be rich in faith and heirs of the Kingdom which he promised to those who love him?"},{"v":6,"t":"But you have dishonored the poor man. Don’t the rich oppress you and personally drag you before the courts?"},{"v":7,"t":"Don’t they blaspheme the honorable name by which you are called?"},{"v":8,"t":"However, if you fulfill the royal law according to the Scripture, “You shall love your neighbor as yourself,” you do well."},{"v":9,"t":"But if you show partiality, you commit sin, being convicted by the law as transgressors."},{"v":10,"t":"For whoever keeps the whole law, and yet stumbles in one point, he has become guilty of all."},{"v":11,"t":"For he who said, “Do not commit adultery,” also said, “Do not commit murder.” Now if you do not commit adultery but do murder, you have become a transgressor of the law."},{"v":12,"t":"So speak and so do as men who are to be judged by the law of freedom."},{"v":13,"t":"For judgment is without mercy to him who has shown no mercy. Mercy triumphs over judgment."},{"v":14,"t":"What good is it, my brothers, if a man says he has faith, but has no works? Can faith save him?"},{"v":15,"t":"And if a brother or sister is naked and in lack of daily food,"},{"v":16,"t":"and one of you tells them, “Go in peace. Be warmed and filled;” yet you didn’t give them the things the body needs, what good is it?"},{"v":17,"t":"Even so faith, if it has no works, is dead in itself."},{"v":18,"t":"Yes, a man will say, “You have faith, and I have works.” Show me your faith without works, and I will show you my faith by my works."},{"v":19,"t":"You believe that God is one. You do well. The demons also believe—and shudder."},{"v":20,"t":"But do you want to know, vain man, that faith apart from works is dead?"},{"v":21,"t":"Wasn’t Abraham our father justified by works, in that he offered up Isaac his son on the altar?"},{"v":22,"t":"You see that faith worked with his works, and by works faith was perfected."},{"v":23,"t":"So the Scripture was fulfilled which says, “Abraham believed God, and it was accounted to him as righteousness,” and he was called the friend of God."},{"v":24,"t":"You see then that by works a man is justified, and not only by faith."},{"v":25,"t":"In the same way, wasn’t Rahab the prostitute also justified by works when she received the messengers and sent them out another way?"},{"v":26,"t":"For as the body apart from the spirit is dead, even so faith apart from works is dead."}],"hr":[{"v":1,"t":"Braćo moja, vjeru Gospodina našega Isusa Krista slavnoga ne miješajte s pristranošću!"},{"v":2,"t":"Dođe li na vaš sastanak čovjek sa zlatnim prstenjem, u sjajnoj odjeći, a dođe i siromah u bijednoj odjeći"},{"v":3,"t":"i vi se zagledate u onoga što nosi sjajnu odjeću te reknete: “Ti lijepo ovdje sjedni!”, a siromahu reknete: “Ti stani - ili sjedni - ondje, podno podnožja moga!”,"},{"v":4,"t":"niste li u sebi pristrano sudili te postali suci što naopako sude?"},{"v":5,"t":"Čujte, braćo moja ljubljena: nije li Bog one koji su svijetu siromašni izabrao da budu bogataši u vjeri i baštinici Kraljevstva što ga je obećao onima koji ga ljube?"},{"v":6,"t":"A vi prezreste siromaha! Ne tlače li vas upravo bogataši? Ne vuku li vas baš oni na sudove?"},{"v":7,"t":"Ne psuju li oni lijepo Ime na vas zazvano?"},{"v":8,"t":"Ako doista izvršujete kraljevski zakon po Pismu: Ljubi bližnjega svoga kao sebe samoga, dobro činite;"},{"v":9,"t":"ako li ste pristrani, grijeh činite i Zakon vas osuđuje kao prijestupnike."},{"v":10,"t":"Ta tko sav Zakon uščuva, a u jednome samo posrne, postao je krivac svega."},{"v":11,"t":"Jer tko reče: Ne čini preljuba, reče i: Ne ubij. Ako dakle i ne činiš preljuba, a ubiješ, postao si prijestupnik Zakona."},{"v":12,"t":"Tako govorite i tako činite kao oni koji imaju biti suđeni po zakonu slobode."},{"v":13,"t":"Jer nemilosrdan je sud onomu tko ne čini milosrđa; a milosrđe likuje nad sudom."},{"v":14,"t":"Što koristi, braćo moja, ako tko rekne da ima vjeru, a djela nema? Može li ga vjera spasiti?"},{"v":15,"t":"Ako su koji brat ili sestra goli i bez hrane svagdanje"},{"v":16,"t":"pa im tkogod od vas rekne: “Hajdete u miru, grijte se i sitite”, a ne dadnete im što je potrebno za tijelo, koja korist?"},{"v":17,"t":"Tako i vjera: ako nema djela, mrtva je u sebi."},{"v":18,"t":"Inače, mogao bi tko reći: “Ti imaš vjeru, a ja imam djela. Pokaži mi svoju vjeru bez djela, a ja ću tebi djelima pokazati svoju vjeru."},{"v":19,"t":"Ti vjeruješ da je jedan Bog? Dobro činiš! I đavli vjeruju, i dršću.”"},{"v":20,"t":"Hoćeš li spoznati, šuplja glavo, da je vjera bez djela jalova?"},{"v":21,"t":"Zar se Abraham, otac naš, ne opravda djelima, kad na žrtvenik prinese Izaka, sina svoga?"},{"v":22,"t":"Vidiš: vjera je surađivala s djelima njegovim i djelima se vjera usavršila"},{"v":23,"t":"te se ispunilo Pismo koje veli: Povjerova Abraham Bogu i uračuna mu se u pravednost pa prijatelj Božji posta."},{"v":24,"t":"Gledajte: čovjek se opravdava djelima, a ne samom vjerom."},{"v":25,"t":"Ne opravda li se slično, djelima, i Rahaba bludnica kad primi glasnike i drugim ih putom izvede?"},{"v":26,"t":"Jer kao što je tijelo bez duha mrtvo, tako je i vjera bez djela mrtva."}]},"3":{"fa":[{"v":1,"t":"ای برادران من، بسیار معلم نشوید چونکه می دانید که بر ما داوری سخت‌تر خواهدشد."},{"v":2,"t":"زیرا همگی ما بسیار می‌لغزیم. و اگر کسی در سخن‌گفتن نلغزد، او مرد کامل است و می‌تواندعنان تمام جسد خود را بکشد."},{"v":3,"t":"و اینک لگام رابر دهان اسبان می‌زنیم تا مطیع ما شوند و تمام بدن آنها را برمی گردانیم."},{"v":4,"t":"اینک کشتیها نیز چقدربزرگ است و از بادهای سخت رانده می‌شود، لکن با سکان کوچک به هر طرفی که اراده ناخدا باشد، برگردانیده می‌شود."},{"v":5,"t":"همچنان زبان نیز عضوی کوچک است و سخنان کبرآمیز می‌گوید. اینک آتش کمی چه جنگل عظیمی را می‌سوزاند."},{"v":6,"t":"وزبان آتشی است! آن عالم ناراستی در میان اعضای ما زبان است که تمام بدن را می‌آلاید ودایره کائنات را می‌سوزاند و از جهنم سوخته می‌شود!"},{"v":7,"t":"زیرا که هر طبیعتی از وحوش و طیور وحشرات و حیوانات بحری از طبیعت انسان رام می‌شود و رام شده است."},{"v":8,"t":"لکن زبان را کسی ازمردمان نمی تواند رام کند. شرارتی سرکش و پر اززهر قاتل است!"},{"v":9,"t":"خدا و پدر را به آن متبارک می‌خوانیم و به همان مردمان را که به صورت خداآفریده شده‌اند، لعن می‌گوییم."},{"v":10,"t":"از یک دهان برکت و لعنت بیرون می‌آید! ای برادران، شایسته نیست که چنین شود."},{"v":11,"t":"آیا چشمه از یک شکاف آب شیرین و شور جاری می‌سازد؟"},{"v":12,"t":"یا می‌شودای برادران من که درخت انجیر، زیتون یا درخت مو، انجیر بار آورد؟ و چشمه شور نمی تواند آب شیرین را موجود سازد."},{"v":13,"t":"کیست در میان شما که حکیم و عالم باشد؟ پس اعمال خود را از سیرت نیکو به تواضع حکمت ظاهر بسازد."},{"v":14,"t":"لکن اگر در دل خودحسد تلخ و تعصب دارید، فخر مکنید و به ضدحق دروغ مگویید."},{"v":15,"t":"این حکمت از بالا نازل نمی شود، بلکه دنیوی و نفسانی و شیطانی است."},{"v":16,"t":"زیرا هرجایی که حسد و تعصب است، درآنجا فتنه و هر امر زشت موجود می‌باشد."},{"v":17,"t":"لکن آن حکمت که از بالا است، اول طاهر است و بعدصلح‌آمیز و ملایم و نصیحت‌پذیر و پر از رحمت و میوه های نیکو و بی‌تردد و بی‌ریا."},{"v":18,"t":"و میوه عدالت در سلامتی کاشته می‌شود برای آنانی که سلامتی را بعمل می‌آورند."}],"en":[{"v":1,"t":"Let not many of you be teachers, my brothers, knowing that we will receive heavier judgment."},{"v":2,"t":"For we all stumble in many things. Anyone who doesn’t stumble in word is a perfect person, able to bridle the whole body also."},{"v":3,"t":"Indeed, we put bits into the horses’ mouths so that they may obey us, and we guide their whole body."},{"v":4,"t":"Behold, the ships also, though they are so big and are driven by fierce winds, are yet guided by a very small rudder, wherever the pilot desires."},{"v":5,"t":"So the tongue is also a little member, and boasts great things. See how a small fire can spread to a large forest!"},{"v":6,"t":"And the tongue is a fire. The world of iniquity among our members is the tongue, which defiles the whole body, and sets on fire the course of nature, and is set on fire by Gehenna."},{"v":7,"t":"For every kind of animal, bird, creeping thing, and sea creature is tamed, and has been tamed by mankind;"},{"v":8,"t":"but nobody can tame the tongue. It is a restless evil, full of deadly poison."},{"v":9,"t":"With it we bless our God and Father, and with it we curse men who are made in the image of God."},{"v":10,"t":"Out of the same mouth comes blessing and cursing. My brothers, these things ought not to be so."},{"v":11,"t":"Does a spring send out from the same opening fresh and bitter water?"},{"v":12,"t":"Can a fig tree, my brothers, yield olives, or a vine figs? Thus no spring yields both salt water and fresh water."},{"v":13,"t":"Who is wise and understanding among you? Let him show by his good conduct that his deeds are done in gentleness of wisdom."},{"v":14,"t":"But if you have bitter jealousy and selfish ambition in your heart, don’t boast and don’t lie against the truth."},{"v":15,"t":"This wisdom is not that which comes down from above, but is earthly, sensual, and demonic."},{"v":16,"t":"For where jealousy and selfish ambition are, there is confusion and every evil deed."},{"v":17,"t":"But the wisdom that is from above is first pure, then peaceful, gentle, reasonable, full of mercy and good fruits, without partiality, and without hypocrisy."},{"v":18,"t":"Now the fruit of righteousness is sown in peace by those who make peace."}],"hr":[{"v":1,"t":"Neka vas, braćo moja, ne bude mnogo učitelja! Ta znate: bit ćemo strože suđeni."},{"v":2,"t":"Doista, svi mnogo griješimo. Ako tko u govoru ne griješi, savršen je čovjek, vrstan zauzdati i cijelo tijelo."},{"v":3,"t":"Ubacimo li uzde u usta konjima da ih sebi upokorimo, upravljamo i cijelim tijelom njihovim."},{"v":4,"t":"Evo i lađa: tolike su i silni ih vjetrovi gone, a neznatno ih kormilo upravlja kamo kormilarova volja hoće."},{"v":5,"t":"Tako i jezik: malen je ud, a velikim se može ponositi. Evo: kolicna vatra koliku šumu zapali!"},{"v":6,"t":"I jezik je vatra, svijet nepravda jezik je među našim udovima, kalja cijelo tijelo te, zapaljen od pakla, zapaljuje kotač života."},{"v":7,"t":"Doista, sav rod zvijeri i ptica, gmazova i morskih životinja dade se ukrotiti, i rod ih je ljudski ukrotio,"},{"v":8,"t":"a jezik - zlo nemirno, pun otrova smrtonosnog - nitko od ljudi ne može ukrotiti."},{"v":9,"t":"Njime blagoslivljamo Gospodina i Oca, njime i proklinjemo ljude na sliku Božju stvorene:"},{"v":10,"t":"iz istih usta izlazi blagoslov i prokletstvo. Ne smije se, braćo moja, tako događati!"},{"v":11,"t":"Zar vrelo na isti otvor šiklja slatko i gorko?"},{"v":12,"t":"Može li, braćo moja, smokva roditi maslinama ili trs smokvama? Ni slan izvor ne može dati slatke vode."},{"v":13,"t":"Je li tko mudar i razborit među vama? Neka dobrim življenjem pokaže svoja djela u mudroj blagosti."},{"v":14,"t":"Ako u srcu imate gorku zavist i svadljivost, ne uznosite se i ne lažite protiv istine!"},{"v":15,"t":"Nije to mudrost koja odozgor silazi, nego zemaljska, ljudska, đavolska."},{"v":16,"t":"Ta gdje je zavist i svadljivost, ondje je nered i svako zlo djelo."},{"v":17,"t":"A mudrost odozgor ponajprije čista je, zatim mirotvorna, milostiva, poučljiva, puna milosrđa i dobrih plodova, postojana, nehinjena."},{"v":18,"t":"Plod se pak pravednosti u miru sije onima koji tvore mir."}]},"4":{"fa":[{"v":1,"t":"از کجا در میان شما جنگها و از کجا نزاعهاپدید می‌آید؟ آیا نه از لذت های شما که دراعضای شما جنگ می‌کند؟"},{"v":2,"t":"طمع می‌ورزید وندارید؛ می‌کشید و حسد می‌نمایید و نمی توانیدبه چنگ آرید؛ و جنگ و جدال می‌کنید و نداریداز این جهت که سوال نمی کنید."},{"v":3,"t":"و سوال می‌کنیدو نمی یابید، از اینرو که به نیت بد سوال می‌کنید تادر لذات خود صرف نمایید."},{"v":4,"t":"‌ای زانیات، آیا نمی دانید که دوستی دنیا، دشمنی خداست؟ پس هرکه می‌خواهد دوست دنیا باشد، دشمن خدا گردد."},{"v":5,"t":"آیا گمان دارید که کتاب عبث می‌گوید روحی که او را در ما ساکن کرده است، تا به غیرت بر ما اشتیاق دارد؟"},{"v":6,"t":"لیکن او فیض زیاده می‌بخشد. بنابراین می‌گوید: «خدامتکبران را مخالفت می‌کند، اما فروتنان را فیض می‌بخشد.»"},{"v":7,"t":"پس خدا را اطاعت نمایید و با ابلیس مقاومت کنید تا از شما بگریزد."},{"v":8,"t":"و به خدا تقرب جویید تا به شما نزدیکی نماید. دستهای خود راطاهر سازید، ای گناهکاران و دلهای خود را پاک کنید، ای دودلان."},{"v":9,"t":"خود را خوار سازید و ناله وگریه نمایید و خنده شما به ماتم و خوشی شما به غم مبدل شود."},{"v":10,"t":"در حضور خدا فروتنی کنید تاشما را سرافراز فرماید."},{"v":11,"t":"‌ای برادران، یکدیگررا ناسزا مگویید زیرا هرکه برادر خود را ناسزاگوید و بر او حکم کند، شریعت را ناسزا گفته و برشریعت حکم کرده باشد. لکن اگر بر شریعت حکم کنی، عامل شریعت نیستی بلکه داورهستی."},{"v":12,"t":"صاحب شریعت و داور، یکی است که بر رهانیدن و هلاک کردن قادر می‌باشد. پس تو کیستی که بر همسایه خود داوری می‌کنی؟"},{"v":13,"t":"هان، ای کسانی که می‌گویید: «امروز و فردابه فلان شهر خواهیم رفت و در آنجا یک سال بسرخواهیم برد و تجارت خواهیم کرد و نفع خواهیم برد»،"},{"v":14,"t":"و حال آنکه نمی دانید که فردا چه می‌شود؛ از آنرو که حیات شما چیست؟ مگربخاری نیستید که اندک زمانی ظاهر است و بعدناپدید می‌شود؟"},{"v":15,"t":"به عوض آنکه باید گفت که «اگر خدا بخواهد، زنده می‌مانیم و چنین و چنان می‌کنیم.»"},{"v":16,"t":"اما الحال به عجب خود فخرمی کنید و هر چنین فخر بد است."},{"v":17,"t":"پس هرکه نیکویی‌کردن بداند و بعمل نیاورد، او را گناه است."}],"en":[{"v":1,"t":"Where do wars and fightings among you come from? Don’t they come from your pleasures that war in your members?"},{"v":2,"t":"You lust, and don’t have. You murder and covet, and can’t obtain. You fight and make war. You don’t have, because you don’t ask."},{"v":3,"t":"You ask, and don’t receive, because you ask with wrong motives, so that you may spend it on your pleasures."},{"v":4,"t":"You adulterers and adulteresses, don’t you know that friendship with the world is hostility toward God? Whoever therefore wants to be a friend of the world makes himself an enemy of God."},{"v":5,"t":"Or do you think that the Scripture says in vain, “The Spirit who lives in us yearns jealously”?"},{"v":6,"t":"But he gives more grace. Therefore it says, “God resists the proud, but gives grace to the humble.”"},{"v":7,"t":"Be subject therefore to God. Resist the devil, and he will flee from you."},{"v":8,"t":"Draw near to God, and he will draw near to you. Cleanse your hands, you sinners. Purify your hearts, you double-minded."},{"v":9,"t":"Lament, mourn, and weep. Let your laughter be turned to mourning and your joy to gloom."},{"v":10,"t":"Humble yourselves in the sight of the Lord, and he will exalt you."},{"v":11,"t":"Don’t speak against one another, brothers. He who speaks against a brother and judges his brother, speaks against the law and judges the law. But if you judge the law, you are not a doer of the law but a judge."},{"v":12,"t":"Only one is the lawgiver, who is able to save and to destroy. But who are you to judge another?"},{"v":13,"t":"Come now, you who say, “Today or tomorrow let’s go into this city and spend a year there, trade, and make a profit.”"},{"v":14,"t":"Yet you don’t know what your life will be like tomorrow. For what is your life? For you are a vapor that appears for a little time and then vanishes away."},{"v":15,"t":"For you ought to say, “If the Lord wills, we will both live, and do this or that.”"},{"v":16,"t":"But now you glory in your boasting. All such boasting is evil."},{"v":17,"t":"To him therefore who knows to do good and doesn’t do it, to him it is sin."}],"hr":[{"v":1,"t":"Odakle ratovi, odakle borbe među vama? Zar ne odavde: od pohota što vojuju u udovima vašim?"},{"v":2,"t":"Žudite, a nemate; ubijate i hlepite, a ne možete postići; borite se i ratujete. Nemate jer ne ištete."},{"v":3,"t":"Ištete, a ne primate jer rđavo ištete: da u pohotama svojim potratite."},{"v":4,"t":"Preljubnici! Ne znate li da je prijateljstvo sa svijetom neprijateljstvo prema Bogu? Tko god dakle hoće da bude prijatelj svijeta, promeće se u neprijatelja Božjega."},{"v":5,"t":"Ili mislite da Pismo uzalud veli: Ljubomorno čezne za duhom što ga nastani u nama?"},{"v":6,"t":"A daje on i veću milost. Zato govori: Bog se oholima protivi, a poniznima daje milost."},{"v":7,"t":"Podložite se dakle Bogu! Oduprite se đavlu i pobjeći će od vas!"},{"v":8,"t":"Približite se Bogu i on će se približiti vama! Očistite ruke, grešnici! Očistite srca, dvoličnjaci!"},{"v":9,"t":"Zakukajte, protužite, proplačite! Smijeh vaš nek se u plač obrati i radost u žalost!"},{"v":10,"t":"Ponizite se pred Gospodinom i on će vas uzvisiti!"},{"v":11,"t":"Ne ogovarajte, braćo, jedni druge! Tko ogovara ili sudi brata svoga, ogovara i sudi Zakon. A sudiš li Zakon, nisi vršitelj nego sudac Zakona."},{"v":12,"t":"Jedan je Zakonodavac i Sudac: Onaj koji može spasiti i pogubiti. A tko si ti da sudiš bližnjega?"},{"v":13,"t":"De sada, vi što govorite: “Danas ili sutra otići ćemo u taj i taj grad, provesti ondje godinu, trgovati i zaraditi”,"},{"v":14,"t":"a ne znate što će sutra biti. Ta što je vaš život? Dašak ste što se načas pojavi i zatim nestane!"},{"v":15,"t":"Umjesto da govorite: “Htjedne li Gospodin, živjet ćemo i učiniti ovo ili ono”,"},{"v":16,"t":"vi se razmećete svojim hvastanjima! Svako je takvo hvastanje opako."},{"v":17,"t":"Znati dakle dobro činiti, a ne činiti - grijeh je."}]},"5":{"fa":[{"v":1,"t":"هان‌ای دولتمندان، بجهت مصیبتهایی که بر شما وارد می‌آید، گریه و ولوله نمایید."},{"v":2,"t":"دولت شما فاسد و رخت شما بیدخورده می‌شود."},{"v":3,"t":"طلا و نقره شما را زنگ می‌خورد وزنگ آنها بر شما شهادت خواهد داد و مثل آتش، گوشت شما را خواهد خورد. شما در زمان آخرخزانه اندوخته‌اید."},{"v":4,"t":"اینک مزد عمله هایی که کشته های شما را درویده‌اند و شما آن را به فریب نگاه داشته‌اید، فریاد برمی آورد و ناله های دروگران، به گوشهای رب الجنود رسیده است."},{"v":5,"t":"بر روی زمین به ناز و کامرانی مشغول بوده، دلهای خود را در یوم قتل پروردید."},{"v":6,"t":"بر مردعادل فتوی دادید و او را به قتل رسانیدید و با شمامقاومت نمی کند."},{"v":7,"t":"پس‌ای برادران، تا هنگام آمدن خداوند صبرکنید. اینک دهقان انتظار می‌کشد برای محصول گرانبهای زمین و برایش صبر می‌کند تا باران اولین و آخرین را بیابد."},{"v":8,"t":"شما نیز صبر نمایید و دلهای خود را قوی سازید زیرا که آمدن خداوند نزدیک است."},{"v":9,"t":"‌ای برادران، از یکدیگر شکایت مکنید، مبادا بر شما حکم شود. اینک داور بر در ایستاده است."},{"v":10,"t":"‌ای برادران، نمونه زحمت و صبر رابگیرید از انبیایی که به نام خداوند تکلم نمودند."},{"v":11,"t":"اینک صابران را خوشحال می‌گوییم و صبرایوب را شنیده‌اید و انجام کار خداوند رادانسته‌اید، زیرا که خداوند بغایت مهربان و کریم است."},{"v":12,"t":"لکن اول همه‌ای برادران من، قسم مخورید نه به آسمان و نه به زمین و نه به هیچ سوگند دیگر، بلکه بلی شما بلی باشد و نی شما نی، مبادا درتحکم بیفتید."},{"v":13,"t":"اگر کسی از شما مبتلای بلایی باشد، دعابنماید و اگر کسی خوشحال باشد، سرود بخواند."},{"v":14,"t":"و هرگاه کسی از شما بیمار باشد، کشیشان کلیسا را طلب کند تا برایش دعا نمایند و او را به نام خداوند به روغن تدهین کنند."},{"v":15,"t":"و دعای ایمان، مریض شما را شفا خواهد بخشید وخداوند او را خواهد برخیزانید، و اگر گناه کرده باشد، از او آمرزیده خواهد شد."},{"v":16,"t":"نزد یکدیگربه گناهان خود اعتراف کنید و برای یکدیگر دعاکنید تا شفا یابید، زیرا دعای مرد عادل در عمل، قوت بسیار دارد."},{"v":17,"t":"الیاس مردی بود صاحب حواس مثل ما و به تمامی دل دعا کرد که باران نبارد و تا مدت سه سال و شش ماه نبارید."},{"v":18,"t":"و بازدعا کرد و آسمان بارید و زمین ثمر خود رارویانید."},{"v":19,"t":"‌ای برادران من، اگر کسی از شما از راستی منحرف شود و شخصی او را بازگرداند،"},{"v":20,"t":"بداندهرکه گناهکار را از ضلالت راه او برگرداند، جانی را از موت رهانیده و گناهان بسیار را پوشانیده است."}],"en":[{"v":1,"t":"Come now, you rich, weep and howl for your miseries that are coming on you."},{"v":2,"t":"Your riches are corrupted and your garments are moth-eaten."},{"v":3,"t":"Your gold and your silver are corroded, and their corrosion will be for a testimony against you and will eat your flesh like fire. You have laid up your treasure in the last days."},{"v":4,"t":"Behold, the wages of the laborers who mowed your fields, which you have kept back by fraud, cry out; and the cries of those who reaped have entered into the ears of the Lord of Armies."},{"v":5,"t":"You have lived in luxury on the earth, and taken your pleasure. You have nourished your hearts as in a day of slaughter."},{"v":6,"t":"You have condemned and you have murdered the righteous one. He doesn’t resist you."},{"v":7,"t":"Be patient therefore, brothers, until the coming of the Lord. Behold, the farmer waits for the precious fruit of the earth, being patient over it, until it receives the early and late rain."},{"v":8,"t":"You also be patient. Establish your hearts, for the coming of the Lord is at hand."},{"v":9,"t":"Don’t grumble, brothers, against one another, so that you won’t be judged. Behold, the judge stands at the door."},{"v":10,"t":"Take, brothers, for an example of suffering and of perseverance, the prophets who spoke in the name of the Lord."},{"v":11,"t":"Behold, we call them blessed who endured. You have heard of the perseverance of Job and have seen the Lord in the outcome, and how the Lord is full of compassion and mercy."},{"v":12,"t":"But above all things, my brothers, don’t swear—not by heaven, or by the earth, or by any other oath; but let your “yes” be “yes”, and your “no”, “no”, so that you don’t fall into hypocrisy."},{"v":13,"t":"Is any among you suffering? Let him pray. Is any cheerful? Let him sing praises."},{"v":14,"t":"Is any among you sick? Let him call for the elders of the assembly, and let them pray over him, anointing him with oil in the name of the Lord;"},{"v":15,"t":"and the prayer of faith will heal him who is sick, and the Lord will raise him up. If he has committed sins, he will be forgiven."},{"v":16,"t":"Confess your sins to one another and pray for one another, that you may be healed. The insistent prayer of a righteous person is powerfully effective."},{"v":17,"t":"Elijah was a man with a nature like ours, and he prayed earnestly that it might not rain, and it didn’t rain on the earth for three years and six months."},{"v":18,"t":"He prayed again, and the sky gave rain, and the earth produced its fruit."},{"v":19,"t":"Brothers, if any among you wanders from the truth and someone turns him back,"},{"v":20,"t":"let him know that he who turns a sinner from the error of his way will save a soul from death and will cover a multitude of sins."}],"hr":[{"v":1,"t":"De sada, bogataši, proplačite i zakukajte zbog nevolja koje će vas zadesiti!"},{"v":2,"t":"Bogatstvo vam istrunu, haljine vaše postadoše hrana moljcima,"},{"v":3,"t":"zlato vam i srebro zarđa i rđa će njihova biti svjedočanstvo protiv vas te će kao vatra izjesti tijela vaša! Zgrnuste blago u posljednje dane!"},{"v":4,"t":"Evo: plaća kosaca vaših njiva - koju im uskratiste - viče i vapaji žetelaca dopriješe do ušiju Gospoda nad Vojskama."},{"v":5,"t":"Raskošno ste na zemlji i razvratno živjeli, utoviste srca svoja za dan klanja!"},{"v":6,"t":"Osudiste i ubiste pravednika: on vam se ne suprotstavlja!"},{"v":7,"t":"Strpite se dakle, braćo, do Dolaska Gospodnjega! Evo: ratar iščekuje dragocjeni urod zemlje, strpljiv je s njime dok ne dobije kišu ranu i kasnu."},{"v":8,"t":"Strpite se i vi, očvrsnite srca jer se Dolazak Gospodnji približio!"},{"v":9,"t":"Ne tužite se jedni na druge da ne budete osuđeni! Evo: sudac stoji pred vratima!"},{"v":10,"t":"Za uzor strpljivosti i podnošenja zala uzmite, braćo, proroke koji su govorili u ime Gospodnje."},{"v":11,"t":"Eto: blaženima nazivamo one koji ustrajaše. Za postojanost Jobovu čuste i nakanu Gospodnju vidjeste jer milostiv je Gospodin i milosrdan!"},{"v":12,"t":"Prije svega, braćo moja, ne zaklinjite se ni nebom ni zemljom, ni ikojom drugom zakletvom. Vaše “da” neka bude “da”, i “ne” - “ne”, da ne padnete pod sud."},{"v":13,"t":"Pati li tko među vama? Neka moli! Je li tko radostan? Neka pjeva hvalospjeve!"},{"v":14,"t":"Boluje li tko među vama? Neka dozove starješine Crkve! Oni neka mole nad njim mažući ga uljem u ime Gospodnje"},{"v":15,"t":"pa će molitva vjere spasiti nemoćnika; Gospodin će ga podići, i ako je sagriješio, oprostit će mu se."},{"v":16,"t":"Ispovijedajte dakle jedni drugima grijehe i molite jedni za druge da ozdravite! Mnogo može žarka molitva pravednikova."},{"v":17,"t":"Ilija bijaše čovjek baš kao i mi; usrdno se pomoli da ne bude kiše i kiše nije bilo na zemlji tri godine i šest mjeseci."},{"v":18,"t":"Zatim se ponovno pomoli te nebo dade kišu i zemlja iznese urod svoj."},{"v":19,"t":"Braćo moja, odluta li tko od vas od istine pa ga tkogod vrati,"},{"v":20,"t":"znajte: tko vrati grešnika s lutalačkog puta njegova, spasit će dušu njegovu od smrti i pokriti mnoštvo grijeha."}]}},"1PE":{"1":{"fa":[{"v":1,"t":"به غریبانی که پراکنده‌اند در پنطس وغلاطیه و قپدوقیه و آسیا و بطانیه؛"},{"v":2,"t":"برگزیدگان برحسب علم سابق خدای پدر، به تقدیس روح برای اطاعت و پاشیدن خون عیسی مسیح. فیض و سلامتی بر شما افزون باد."},{"v":3,"t":"متبارک باد خدا و پدر خداوند ما عیسی مسیح که بحسب رحمت عظیم خود ما رابوساطت برخاستن عیسی مسیح از مردگان از نوتولید نمود برای امید زنده،"},{"v":4,"t":"بجهت میراث بی‌فساد و بی‌آلایش و ناپژمرده که نگاه داشته شده است در آسمان برای شما؛"},{"v":5,"t":"که به قوت خدامحروس هستید به ایمان برای نجاتی که مهیاشده است تا در ایام آخر ظاهر شود."},{"v":6,"t":"و در آن وجد می‌نمایید، هرچند در حال، اندکی از راه ضرورت در تجربه های گوناگون محزون شده‌اید،"},{"v":7,"t":"تا آزمایش ایمان شما که از طلای فانی باآزموده شدن در آتش، گرانبهاتر است، برای تسبیح و جلال و اکرام یافت شود در حین ظهورعیسی مسیح."},{"v":8,"t":"که او را اگرچه ندیده‌اید محبت می‌نمایید و الان اگرچه او را نمی بینید، لکن بر اوایمان آورده، وجد می‌نمایید با خرمی‌ای که نمی توان بیان کرد و پر از جلال است."},{"v":9,"t":"و انجام ایمان خود یعنی نجات جان خویش را می‌یابید."},{"v":10,"t":"که درباره این نجات، انبیایی که از فیضی که برای شما مقرر بود، اخبار نمودند، تفتیش وتفحص می‌کردند"},{"v":11,"t":"و دریافت می‌نمودند که کدام و چگونه زمان است که روح مسیح که درایشان بود از آن خبر می‌داد، چون از زحماتی که برای مسیح مقرر بود و جلالهایی که بعد از آنهاخواهد بود، شهادت می‌داد؛"},{"v":12,"t":"و بدیشان مکشوف شد که نه به خود بلکه به ما خدمت می‌کردند، در آن اموری که شما اکنون از آنها خبریافته‌اید از کسانی که به روح‌القدس که از آسمان فرستاده شده است، بشارت داده‌اند و فرشتگان نیز مشتاق هستند که در آنها نظر کنند."},{"v":13,"t":"لهذا کمر دلهای خود را ببندید و هشیارشده، امید کامل آن فیضی را که در مکاشفه عیسی مسیح به شما عطا خواهد شد، بدارید."},{"v":14,"t":"و چون ابنای اطاعت هستید، مشابه مشوید بدان شهواتی که در ایام جهالت می‌داشتید."},{"v":15,"t":"بلکه مثل آن قدوس که شما را خوانده است، خود شما نیز درهر سیرت، مقدس باشید."},{"v":16,"t":"زیرا مکتوب است: «مقدس باشید زیرا که من قدوسم.»"},{"v":17,"t":"و چون او را پدر می‌خوانید که بدون ظاهربینی برحسب اعمال هرکس داوری می‌نماید، پس هنگام غربت خود را با ترس صرف نمایید."},{"v":18,"t":"زیرا می‌دانید که خریده شده‌اید از سیرت باطلی که از پدران خود یافته‌اید نه به چیزهای فانی مثل نقره و طلا،"},{"v":19,"t":"بلکه به خون گرانبها چون خون بره بی‌عیب و بی‌داغ یعنی خون مسیح،"},{"v":20,"t":"که پیش از بنیاد عالم معین شد، لکن درزمان آخر برای شما ظاهر گردید،"},{"v":21,"t":"که بوساطت او شما بر آن خدایی که او را از مردگان برخیزانیدو او را جلال داد، ایمان آورده‌اید تا ایمان و امیدشما بر خدا باشد."},{"v":22,"t":"چون نفسهای خود را به اطاعت راستی طاهر ساخته‌اید تا محبت برادرانه بی‌ریا داشته باشید، پس یکدیگر را از دل بشدت محبت بنمایید."},{"v":23,"t":"از آنرو که تولد تازه یافتید نه از تخم فانی بلکه از غیرفانی یعنی به کلام خدا که زنده وتا ابدالاباد باقی است."},{"v":24,"t":"زیرا که «هر بشری مانندگیاه است و تمام جلال او چون گل گیاه. گیاه پژمرده شد و گلش ریخت."},{"v":25,"t":"لکن کلمه خدا تاابدالاباد باقی است.» و این است آن کلامی که به شما بشارت داده شده است."}],"en":[{"v":1,"t":"Peter, an apostle of Jesus Christ, to the chosen ones who are living as foreigners in the Dispersion in Pontus, Galatia, Cappadocia, Asia, and Bithynia,"},{"v":2,"t":"according to the foreknowledge of God the Father, in sanctification of the Spirit, that you may obey Jesus Christ and be sprinkled with his blood: Grace to you and peace be multiplied."},{"v":3,"t":"Blessed be the God and Father of our Lord Jesus Christ, who according to his great mercy caused us to be born again to a living hope through the resurrection of Jesus Christ from the dead,"},{"v":4,"t":"to an incorruptible and undefiled inheritance that doesn’t fade away, reserved in Heaven for you,"},{"v":5,"t":"who by the power of God are guarded through faith for a salvation ready to be revealed in the last time."},{"v":6,"t":"In this you greatly rejoice, though now for a little while, if need be, you have been grieved in various trials,"},{"v":7,"t":"that the proof of your faith, which is more precious than gold that perishes, even though it is tested by fire, may be found to result in praise, glory, and honor at the revelation of Jesus Christ—"},{"v":8,"t":"whom, not having known, you love. In him, though now you don’t see him, yet believing, you rejoice greatly with joy that is unspeakable and full of glory,"},{"v":9,"t":"receiving the result of your faith, the salvation of your souls."},{"v":10,"t":"Concerning this salvation, the prophets sought and searched diligently. They prophesied of the grace that would come to you,"},{"v":11,"t":"searching for who or what kind of time the Spirit of Christ which was in them pointed to when he predicted the sufferings of Christ and the glories that would follow them."},{"v":12,"t":"To them it was revealed that they served not themselves, but you, in these things, which now have been announced to you through those who preached the Good News to you by the Holy Spirit sent out from heaven; which things angels desire to look into."},{"v":13,"t":"Therefore prepare your minds for action. Be sober, and set your hope fully on the grace that will be brought to you at the revelation of Jesus Christ—"},{"v":14,"t":"as children of obedience, not conforming yourselves according to your former lusts as in your ignorance,"},{"v":15,"t":"but just as he who called you is holy, you yourselves also be holy in all of your behavior,"},{"v":16,"t":"because it is written, “You shall be holy, for I am holy.”"},{"v":17,"t":"If you call on him as Father, who without respect of persons judges according to each man’s work, pass the time of your living as foreigners here in reverent fear,"},{"v":18,"t":"knowing that you were redeemed, not with corruptible things like silver or gold, from the useless way of life handed down from your fathers,"},{"v":19,"t":"but with precious blood, as of a lamb without blemish or spot, the blood of Christ,"},{"v":20,"t":"who was foreknown indeed before the foundation of the world, but was revealed in this last age for your sake,"},{"v":21,"t":"who through him are believers in God, who raised him from the dead and gave him glory, so that your faith and hope might be in God."},{"v":22,"t":"Seeing you have purified your souls in your obedience to the truth through the Spirit in sincere brotherly affection, love one another from the heart fervently,"},{"v":23,"t":"having been born again, not of corruptible seed, but of incorruptible, through the word of God, which lives and remains forever."},{"v":24,"t":"For, “All flesh is like grass, and all of man’s glory like the flower in the grass. The grass withers, and its flower falls;"},{"v":25,"t":"but the Lord’s word endures forever.” This is the word of Good News which was preached to you."}],"hr":[{"v":1,"t":"Petar, apostol Isusa Krista: putnicima Raseljeništva u Pontu, Galaciji, Kapadociji, Aziji i Bitiniji,"},{"v":2,"t":"po predznanju Boga Oca, posvećenjem Duha izabranima da budu poslušni te poškropljeni krvlju Isusa Krista. Punina vam milosti i mira!"},{"v":3,"t":"Blagoslovljen Bog i Otac Gospodina našega Isusa Krista koji nas po velikom milosrđu svojemu uskrsnućem Isusa Krista od mrtvih nanovo rodi za životnu nadu,"},{"v":4,"t":"za baštinu neraspadljivu, neokaljanu i neuvelu, pohranjenu na nebesima za vas,"},{"v":5,"t":"vas koje snaga Božja po vjeri čuva za spasenje, spremno da se objavi u posljednje vrijeme."},{"v":6,"t":"Zbog toga se radujte, makar se sada možda trebalo malo i žalostiti zbog različitih kušnja:"},{"v":7,"t":"da prokušanost vaše vjere - dragocjenija od propadljivog zlata, koje se ipak u vatri kuša - stekne hvalu, slavu i čast o Objavljenju Isusa Krista."},{"v":8,"t":"Njega vi ljubite iako ga ne vidjeste; u njega, iako ga još ne gledate, vjerujete te klikćete od radosti neizrecive i proslavljene"},{"v":9,"t":"što postigoste svrhu svoje vjere: spasenje duša."},{"v":10,"t":"To su spasenje istraživali i pronicali proroci koji prorokovahu o milosti vama namijenjenoj."},{"v":11,"t":"Pronicali su na koje ili kakvo je vrijeme smjerao Duh Kristov u njima koji je unaprijed svjedočio o Kristovim patnjama te slavama što su nakon njih imale doći:"},{"v":12,"t":"bi im objavljeno da ne sebi nego vama poslužuju ono što vam sada u Duhu Svetom s neba poslanom navijestiše vaši blagovjesnici, a nada što se i anđeli žude nadviti."},{"v":13,"t":"Zato opašite bokove pameti svoje, trijezni budite i savršeno se pouzdajte u milost koju vam donosi Objavljenje Isusa Krista."},{"v":14,"t":"Kao poslušna djeca ne supriličujte se prijašnjim požudama iz doba neznanja."},{"v":15,"t":"Naprotiv, kao što je svet Onaj koji vas pozva, i vi budite sveti u svemu življenju."},{"v":16,"t":"Ta pisano je: Budite sveti jer sam ja svet."},{"v":17,"t":"Ako dakle Ocem nazivate njega koji nepristrano svakoga po djelu sudi, vrijeme svoga proputovanja proživite u bogobojaznosti."},{"v":18,"t":"Ta znate da od svog ispraznog načina života, što vam ga oci namriješe, niste otkupljeni nečim raspadljivim, srebrom ili zlatom,"},{"v":19,"t":"nego dragocjenom krvlju Krista, Jaganjca nevina i bez mane."},{"v":20,"t":"On bijaše doduše predviđen prije postanka svijeta, ali se očitova na kraju vremena radi vas"},{"v":21,"t":"koji po njemu vjerujete u Boga koji ga uskrisi od mrtvih te mu dade slavu da vjera vaša i nada bude u Bogu."},{"v":22,"t":"Pošto ste posluhom istini očistili duše svoje za nehinjeno bratoljublje, od srca žarko ljubite jedni druge."},{"v":23,"t":"Ta nanovo ste rođeni, ne iz sjemena raspadljiva nego neraspadljiva: riječju Boga koji živi i ostaje."},{"v":24,"t":"Doista, svako je tijelo kao trava, sva mu slava ko cvijet poljski: sahne trava, vene cvijet,"},{"v":25,"t":"ali Riječ Gospodnja ostaje dovijeka. Ta pak riječ jest evanđelje koje vam je naviješteno."}]},"2":{"fa":[{"v":1,"t":"لهذا هر نوع کینه و هر مکر و ریا و حسد وهرقسم بدگویی را ترک کرده،"},{"v":2,"t":"چون اطفال نوزاده، مشتاق شیر روحانی و بی‌غش باشید تا از آن برای نجات نمو کنید،"},{"v":3,"t":"اگرفی الواقع چشیده‌اید که خداوند مهربان است."},{"v":4,"t":"و به او تقرب جسته، یعنی به آن سنگ زنده رد شده از مردم، لکن نزد خدا برگزیده و مکرم."},{"v":5,"t":"شما نیز مثل سنگهای زنده بنا کرده می‌شوید به عمارت روحانی و کهانت مقدس تا قربانی های روحانی و مقبول خدا را بواسطه عیسی مسیح بگذرانید."},{"v":6,"t":"بنابراین، در کتاب مکتوب است که «اینک می‌نهم در صهیون سنگی سر زاویه برگزیده و مکرم و هر‌که به وی ایمان آورد خجل نخواهد شد.»"},{"v":7,"t":"پس شما را که ایمان دارید اکرام است، لکن آنانی را که ایمان ندارند، «آن سنگی که معماران رد کردند، همان سر زاویه گردید»،"},{"v":8,"t":"و «سنگ لغزش دهنده و صخره مصادم»، زیرا که اطاعت کلام نکرده، لغزش می‌خورند که برای همین معین شده‌اند."},{"v":9,"t":"لکن شما قبیله برگزیده و کهانت ملوکانه وامت مقدس و قومی که ملک خاص خدا باشدهستید تا فضایل او را که شما را از ظلمت، به نورعجیب خود خوانده است، اعلام نمایید."},{"v":10,"t":"که سابق قومی نبودید و الان قوم خدا هستید. آن وقت از رحمت محروم، اما الحال رحمت کرده شده‌اید."},{"v":11,"t":"‌ای محبوبان، استدعا دارم که چون غریبان و بیگانگان از شهوات جسمی که با نفس در نزاع هستند، اجتناب نمایید؛"},{"v":12,"t":"و سیرت خود را درمیان امت‌ها نیکو دارید تا در همان امری که شمارا مثل بدکاران بد می‌گویند، از کارهای نیکوی شما که ببینند، در روز تفقد، خدا را تمجیدنمایند."},{"v":13,"t":"لهذا هر منصب بشری را بخاطر خداونداطاعت کنید، خواه پادشاه را که فوق همه است،"},{"v":14,"t":"و خواه حکام را که رسولان وی هستند، بجهت انتقام کشیدن از بدکاران و تحسین نیکوکاران."},{"v":15,"t":"زیرا که همین است اراده خدا که به نیکوکاری خود، جهالت مردمان بی‌فهم را ساکت نمایید،"},{"v":16,"t":"مثل آزادگان، اما نه مثل آنانی که آزادی خود را پوشش شرارت می‌سازند بلکه چون بندگان خدا."},{"v":17,"t":"همه مردمان را احترام کنید. برادران را محبت نمایید. از خدا بترسید. پادشاه رااحترام نمایید."},{"v":18,"t":"‌ای نوکران، مطیع آقایان خود باشید با کمال ترس؛ و نه فقط صالحان و مهربانان را بلکه کج خلقان را نیز."},{"v":19,"t":"زیرا این ثواب است که کسی بجهت ضمیری که چشم بر خدا دارد، در وقتی که ناحق زحمت می‌کشد، دردها را متحمل شود."},{"v":20,"t":"زیرا چه فخر دارد هنگامی که گناهکار بوده، تازیانه خورید و متحمل آن شوید. لکن اگرنیکوکار بوده، زحمت کشید و صبر کنید، این نزدخدا ثواب است."},{"v":21,"t":"زیرا که برای همین خوانده شده‌اید، چونکه مسیح نیز برای ما عذاب کشید وشما را نمونه‌ای گذاشت تا در اثر قدمهای وی رفتار نمایید،"},{"v":22,"t":"«که هیچ گناه نکرد و مکر درزبانش یافت نشد.»"},{"v":23,"t":"چون او را دشنام می‌دادند، دشنام پس نمی داد و چون عذاب می‌کشید تهدیدنمی نمود، بلکه خویشتن را به داور عادل تسلیم کرد."},{"v":24,"t":"که خود گناهان ما را در بدن خویش بردارمتحمل شد تا از گناه مرده شده، به عدالت زیست نماییم که به ضربهای او شفا یافته‌اید."},{"v":25,"t":"از آنروکه مانند گوسفندان گمشده بودید، لکن الحال به سوی شبان و اسقف جانهای خود برگشته‌اید."}],"en":[{"v":1,"t":"Putting away therefore all wickedness, all deceit, hypocrisies, envies, and all evil speaking,"},{"v":2,"t":"as newborn babies, long for the pure spiritual milk, that with it you may grow,"},{"v":3,"t":"if indeed you have tasted that the Lord is gracious."},{"v":4,"t":"Come to him, a living stone, rejected indeed by men, but chosen by God, precious."},{"v":5,"t":"You also as living stones are built up as a spiritual house, to be a holy priesthood, to offer up spiritual sacrifices, acceptable to God through Jesus Christ."},{"v":6,"t":"Because it is contained in Scripture, “Behold, I lay in Zion a chief cornerstone, chosen and precious. He who believes in him will not be disappointed.”"},{"v":7,"t":"For you who believe therefore is the honor, but for those who are disobedient, “The stone which the builders rejected has become the chief cornerstone,”"},{"v":8,"t":"and, “a stumbling stone and a rock of offense.” For they stumble at the word, being disobedient, to which also they were appointed."},{"v":9,"t":"But you are a chosen race, a royal priesthood, a holy nation, a people for God’s own possession, that you may proclaim the excellence of him who called you out of darkness into his marvelous light."},{"v":10,"t":"In the past, you were not a people, but now are God’s people, who had not obtained mercy, but now have obtained mercy."},{"v":11,"t":"Beloved, I beg you as foreigners and pilgrims to abstain from fleshly lusts which war against the soul,"},{"v":12,"t":"having good behavior among the nations, so in that of which they speak against you as evildoers, they may see your good works and glorify God in the day of visitation."},{"v":13,"t":"Therefore subject yourselves to every ordinance of man for the Lord’s sake: whether to the king, as supreme,"},{"v":14,"t":"or to governors, as sent by him for vengeance on evildoers and for praise to those who do well."},{"v":15,"t":"For this is the will of God, that by well-doing you should put to silence the ignorance of foolish men."},{"v":16,"t":"Live as free people, yet not using your freedom for a cloak of wickedness, but as bondservants of God."},{"v":17,"t":"Honor all men. Love the brotherhood. Fear God. Honor the king."},{"v":18,"t":"Servants, be in subjection to your masters with all respect, not only to the good and gentle, but also to the wicked."},{"v":19,"t":"For it is commendable if someone endures pain, suffering unjustly, because of conscience toward God."},{"v":20,"t":"For what glory is it if, when you sin, you patiently endure beating? But if when you do well, you patiently endure suffering, this is commendable with God."},{"v":21,"t":"For you were called to this, because Christ also suffered for us, leaving you an example, that you should follow his steps,"},{"v":22,"t":"who didn’t sin, “neither was deceit found in his mouth.”"},{"v":23,"t":"When he was cursed, he didn’t curse back. When he suffered, he didn’t threaten, but committed himself to him who judges righteously."},{"v":24,"t":"He himself bore our sins in his body on the tree, that we, having died to sins, might live to righteousness. You were healed by his wounds."},{"v":25,"t":"For you were going astray like sheep; but now you have returned to the Shepherd and Overseer of your souls."}],"hr":[{"v":1,"t":"Odložite dakle svaku zloću i svaku prijevaru, himbe i zavisti i sva klevetanja."},{"v":2,"t":"Kao novorođenčad žudite za duhovnim, nepatvorenim mlijekom da po njemu uzrastete za spasenje,"},{"v":3,"t":"ako ste doista okusili kako je dobar Gospodin."},{"v":4,"t":"Pristupite k njemu, Kamenu živomu što ga, istina, ljudi odbaciše, ali je u očima Božjim izabran, dragocjen,"},{"v":5,"t":"pa se kao živo kamenje ugrađujte u duhovni Dom za sveto svećenstvo da prinosite žrtve duhovne, ugodne Bogu po Isusu Kristu."},{"v":6,"t":"Stoga stoji u Pismu: Evo postavljam na Sionu kamen odabrani, dragocjeni kamen ugaoni: Tko u nj vjeruje, ne, neće se postidjeti."},{"v":7,"t":"Vama dakle koji vjerujete - čast! A onima koji ne vjeruju - kamen koji odbaciše graditelji postade kamen zaglavni"},{"v":8,"t":"i kamen spoticanja, stijena posrtanja; oni se o nj spotiču, neposlušni Riječi, za što su i određeni."},{"v":9,"t":"A vi ste rod izabrani, kraljevsko svećenstvo, sveti puk, narod stečeni da naviještate silna djela Onoga koji vas iz tame pozva k divnom svjetlu svojemu;"},{"v":10,"t":"vi, nekoć Ne-narod, a sada Narod Božji; vi Ne-mili, a sada Mili."},{"v":11,"t":"Ljubljeni! Zaklinjem vas da se kao pridošlice i putnici klonite putenih požuda koje vojuju protiv duše;"},{"v":12,"t":"življenje vaše među poganima neka bude uzorno da upravo onim za što vas sada potvaraju kao zločince, pošto promotre vaša dobra djela, proslave Boga u dan pohoda."},{"v":13,"t":"Pokoravajte se svakoj ljudskoj ustanovi radi Gospodina: bilo kralju kao vrhovniku,"},{"v":14,"t":"bilo upraviteljima jer ih on šalje da kazne zločince, a pohvale one koji dobro čine."},{"v":15,"t":"Doista, ovo je Božja volja: da čineći dobro ušutkate neznanje bezumnika."},{"v":16,"t":"Kao slobodni ljudi - ali ne kao oni kojima je sloboda tek pokrivalom zloće, već kao Božje sluge -"},{"v":17,"t":"sve poštujte, bratstvo ljubite, Boga se bojte, kralja častite!"},{"v":18,"t":"Sluge, budite sa svim poštovanjem pokorni gospodarima, ne samo dobrima i blagima nego i naopakima."},{"v":19,"t":"To je uistinu milost ako tko radi savjesti, radi Boga podnosi nevolje trpeći nepravedno."},{"v":20,"t":"Kakve li slave doista ako za grijehe udarani strpljivo podnosite? No ako dobro čineći trpite pa strpljivo podnosite, to je Bogu milo."},{"v":21,"t":"Ta na to ste pozvani jer i Krist je trpio za vas i ostavio vam primjer da idete stopama njegovim."},{"v":22,"t":"On koji grijeha ne učini nit mu usta prijevaru izustiše;"},{"v":23,"t":"on koji na uvredu nije uvredom uzvraćao i mučen nije prijetio, prepuštajući to Sucu pravednom;"},{"v":24,"t":"on koji u tijelu svom grijehe naše ponese na drvo da umrijevši grijesima pravednosti živimo; on čijom se modricom izliječiste."},{"v":25,"t":"Doista, poput ovaca lutaste, ali se sada obratiste k pastiru i čuvaru duša svojih."}]},"3":{"fa":[{"v":1,"t":"همچنین‌ای زنان، شوهران خود را اطاعت نمایید تا اگر بعضی نیز مطیع کلام نشوند، سیرت زنان، ایشان را بدون کلام دریابد،"},{"v":2,"t":"چونکه سیرت طاهر و خداترس شما را بینند."},{"v":3,"t":"و شما رازینت ظاهری نباشد، از بافتن موی و متحلی شدن به طلا و پوشیدن لباس،"},{"v":4,"t":"بلکه انسانیت باطنی قلبی در لباس غیر فاسد روح حلیم و آرام که نزدخدا گرانبهاست."},{"v":5,"t":"زیرا بدینگونه زنان مقدسه درسابق نیز که متوکل به خدا بودند، خویشتن رازینت می‌نمودند و شوهران خود را اطاعت می‌کردند."},{"v":6,"t":"مانند ساره که ابراهیم را مطیع می‌بودو او را آقا می‌خواند و شما دختران او شده‌اید، اگر نیکویی کنید و از هیچ خوف ترسان نشوید."},{"v":7,"t":"و همچنین‌ای شوهران، با فطانت با ایشان زیست کنید، چون با ظروف ضعیف تر زنانه، وایشان را محترم دارید چون با شما وارث فیض حیات نیز هستند تا دعاهای شما بازداشته نشود."},{"v":8,"t":"خلاصه همه شما یکرای و همدرد و برادردوست و مشفق و فروتن باشید."},{"v":9,"t":"و بدی بعوض بدی و دشنام بعوض دشنام مدهید، بلکه برعکس برکت بطلبید زیرا که می‌دانید برای این خوانده شده‌اید تا وارث برکت شوید."},{"v":10,"t":"زیرا «هرکه می‌خواهد حیات را دوست دارد و ایام نیکو بیند، زبان خود را از بدی و لبهای خود را از فریب گفتن باز بدارد؛"},{"v":11,"t":"از بدی اعراض نماید و نیکویی رابه‌جا آورد؛ سلامتی را بطلبد و آن را تعاقب نماید."},{"v":12,"t":"از آنرو که چشمان خداوند بر عادلان است وگوشهای او به سوی دعای ایشان، لکن روی خداوند بر بدکاران است.»"},{"v":13,"t":"و اگر برای نیکویی غیور هستید، کیست که به شما ضرری برساند؟"},{"v":14,"t":"بلکه هرگاه برای عدالت زحمت کشیدید، خوشابحال شما. پس ازخوف ایشان ترسان و مضطرب مشوید."},{"v":15,"t":"بلکه خداوند مسیح را در دل خود تقدیس نمایید وپیوسته مستعد باشید تا هرکه سبب امیدی را که دارید از شما بپرسد، او را جواب دهید، لیکن باحلم و ترس."},{"v":16,"t":"و ضمیر خود را نیکو بدارید تاآنانی که بر سیرت نیکوی شما در مسیح طعن می‌زنند، در همان چیزی که شما را بد می‌گویندخجالت کشند،"},{"v":17,"t":"زیرا اگر اراده خدا چنین است، نیکوکار بودن و زحمت کشیدن، بهتر است ازبدکردار بودن."},{"v":18,"t":"زیرا که مسیح نیز برای گناهان یک بار زحمت کشید، یعنی عادلی برای ظالمان، تا ما را نزد خدا بیاورد؛ در حالیکه بحسب جسم مرد، لکن بحسب روح زنده گشت،"},{"v":19,"t":"و به آن روح نیز رفت و موعظه نمود به ارواحی که درزندان بودند،"},{"v":20,"t":"که سابق نافرمانبردار بودندهنگامی که حلم خدا در ایام نوح انتظار می‌کشید، وقتی که کشتی بنا می‌شد، که در آن جماعتی قلیل یعنی هشت نفر به آب نجات یافتند،"},{"v":21,"t":"که نمونه آن یعنی تعمید اکنون ما را نجات می‌بخشد (نه دور کردن کثافت جسم بلکه امتحان ضمیر صالح به سوی خدا) بواسطه برخاستن عیسی مسیح،"},{"v":22,"t":"که به آسمان رفت و بدست راست خدا است وفرشتگان و قدرتها و قوات مطیع او شده‌اند."}],"en":[{"v":1,"t":"In the same way, wives, be in subjection to your own husbands, so that, even if any don’t obey the Word, they may be won by the behavior of their wives without a word,"},{"v":2,"t":"seeing your pure behavior in fear."},{"v":3,"t":"Let your beauty come not from the outward adorning of braiding your hair, and of wearing gold ornaments or of putting on fine clothing,"},{"v":4,"t":"but from the hidden person of the heart, in the incorruptible adornment of a gentle and quiet spirit, which is very precious in God’s sight."},{"v":5,"t":"For this is how in the past the holy women who hoped in God also adorned themselves, being in subjection to their own husbands."},{"v":6,"t":"So Sarah obeyed Abraham, calling him lord, whose children you now are if you do well and are not put in fear by any terror."},{"v":7,"t":"You husbands, in the same way, live with your wives according to knowledge, giving honor to the woman as to the weaker vessel, as also being joint heirs of the grace of life, that your prayers may not be hindered."},{"v":8,"t":"Finally, all of you be like-minded, compassionate, loving as brothers, tenderhearted, courteous,"},{"v":9,"t":"not rendering evil for evil or insult for insult; but instead blessing, knowing that you were called to this, that you may inherit a blessing."},{"v":10,"t":"For, “He who would love life and see good days, let him keep his tongue from evil and his lips from speaking deceit."},{"v":11,"t":"Let him turn away from evil and do good. Let him seek peace and pursue it."},{"v":12,"t":"For the eyes of the Lord are on the righteous, and his ears open to their prayer; but the face of the Lord is against those who do evil.”"},{"v":13,"t":"Now who will harm you if you become imitators of that which is good?"},{"v":14,"t":"But even if you should suffer for righteousness’ sake, you are blessed. “Don’t fear what they fear, neither be troubled.”"},{"v":15,"t":"But sanctify the Lord God in your hearts. Always be ready to give an answer to everyone who asks you a reason concerning the hope that is in you, with humility and fear,"},{"v":16,"t":"having a good conscience. Thus, while you are spoken against as evildoers, they may be disappointed who curse your good way of life in Christ."},{"v":17,"t":"For it is better, if it is God’s will, that you suffer for doing what is right than for doing evil."},{"v":18,"t":"Because Christ also suffered for sins once, the righteous for the unrighteous, that he might bring you to God, being put to death in the flesh, but made alive in the Spirit,"},{"v":19,"t":"in whom he also went and preached to the spirits in prison,"},{"v":20,"t":"who before were disobedient when God waited patiently in the days of Noah while the ship was being built. In it, few, that is, eight souls, were saved through water."},{"v":21,"t":"This is a symbol of baptism, which now saves you—not the putting away of the filth of the flesh, but the answer of a good conscience toward God—through the resurrection of Jesus Christ,"},{"v":22,"t":"who is at the right hand of God, having gone into heaven, angels and authorities and powers being made subject to him."}],"hr":[{"v":1,"t":"Tako i vi, žene, pokoravajte se svojim muževima: ako su neki od njih možda neposlušni Riječi, da i bez riječi budu pridobiveni življenjem vas žena,"},{"v":2,"t":"pošto promotre vaše bogoljubno i čisto življenje."},{"v":3,"t":"Vaš nakit neka ne bude izvanjski - pletenje kose, kićenje zlatom ili oblačenje haljina."},{"v":4,"t":"Nego: čovjek skrovita srca, neprolazne ljepote, blaga i smirena duha. To je pred Bogom dragocjeno."},{"v":5,"t":"Tako su se doista i nekoć svete žene, zaufane u Boga, resile: pokoravale su se muževima."},{"v":6,"t":"Sara se tako pokori Abrahamu te ga nazva gospodarom. Njezina ste djeca ako činite dobro ne bojeći se nikakva zastrašivanja."},{"v":7,"t":"Tako i vi, muževi, obazrivo živite sa svojim ženama, kao sa slabijim spolom, te im iskazujte čast kao subaštinicima milosti Života da ne spriječite svojih molitava."},{"v":8,"t":"Napokon, budite svi jednodušni, puni suosjećanja i bratske ljubavi, milosrdni, ponizni!"},{"v":9,"t":"Ne vraćajte zlo za zlo ni uvredu za uvredu! Naprotiv, blagoslivljajte jer ste na to i pozvani da baštinite blagoslov!"},{"v":10,"t":"Doista, tko želi ljubiti život i naužit se dana sretnih, nek suspregne jezik oda zla i usne od riječi prijevarnih;"},{"v":11,"t":"zla nek se kloni, a čini dobro, mir neka traži i za njim ide:"},{"v":12,"t":"jer oči Gospodnje gledaju pravedne, uši mu slušaju vapaje njihove, a lice se Gospodnje okreće protiv zločinaca."},{"v":13,"t":"Pa tko da vam naudi ako revnujete za dobro?"},{"v":14,"t":"Nego, morali i trpjeti zbog svoje pravednosti, blago vama! No ne bojte se njihova zastrašivanja i ne plašite se!"},{"v":15,"t":"Naprotiv, Gospodin - Krist neka vam bude svet, u srcima vašim, te budite uvijek spremni na odgovor svakomu koji od vas zatraži obrazloženje nade koja je u vama,"},{"v":16,"t":"ali blago i s poštovanjem, dobre savjesti da oni koji ozloglašuju vaš dobar život u Kristu, upravo onim budu postiđeni za što vas potvaraju."},{"v":17,"t":"Ta uspješnije je trpjeti, ako je to Božja volja, čineći dobro, nego čineći zlo."},{"v":18,"t":"Doista, i Krist jednom za grijehe umrije, pravedan za nepravedne, da vas privede k Bogu - ubijen doduše u tijelu, ali oživljen u duhu."},{"v":19,"t":"U njemu otiđe i propovijedati duhovima u tamnici"},{"v":20,"t":"koji bijahu nekoć nepokorni, kad ih ono Božja strpljivost iščekivaše, u vrijeme Noino, dok se gradila korablja u kojoj nekolicina, to jest osam duša, bi spašena vodom."},{"v":21,"t":"Njezin protulik, krštenje - ne odlaganje tjelesne nečistoće, nego molitva za dobru savjest upravljena Bogu - i vas sada spasava po uskrsnuću Isusa Krista"},{"v":22,"t":"koji, uzašavši na nebo, jest zdesna Bogu, pošto mu bijahu pokoreni anđeli, vlasti i sile."}]},"4":{"fa":[{"v":1,"t":"لهذا چون مسیح بحسب جسم برای مازحمت کشید، شما نیز به همان نیت مسلح شوید زیرا آنکه بحسب جسم زحمت کشید، ازگناه بازداشته شده است."},{"v":2,"t":"تا آنکه بعد از آن مابقی عمر را در جسم نه بحسب شهوات انسانی بلکه موافق اراده خدا بسر برد."},{"v":3,"t":"زیرا که عمر گذشته کافی است برای عمل نمودن به خواهش امت‌ها ودر فجور و شهوات و می‌گساری و عیاشی و بزمهاو بت‌پرستیهای حرام رفتار نمودن."},{"v":4,"t":"و در این متعجب هستند که شما همراه ایشان به سوی همین اسراف اوباشی نمی شتابید و شما را دشنام می‌دهند."},{"v":5,"t":"و ایشان حساب خواهند داد بدو که مستعد است تا زندگان و مردگان را داوری نماید."},{"v":6,"t":"زیرا که از اینجهت نیز به مردگان بشارت داده شد تا بر ایشان موافق مردم بحسب جسم حکم شود و موافق خدا بحسب روح زیست نمایند."},{"v":7,"t":"لکن انتهای همه‌چیز نزدیک است. پس خرداندیش و برای دعا هشیار باشید."},{"v":8,"t":"و اول همه با یکدیگر بشدت محبت نمایید زیرا که محبت کثرت گناهان را می‌پوشاند."},{"v":9,"t":"و یکدیگر را بدون همهمه مهمانی کنید."},{"v":10,"t":"و هریک بحسب نعمتی که یافته باشد، یکدیگر را در آن خدمت نماید، مثل وکلاء امین فیض گوناگون خدا."},{"v":11,"t":"اگر کسی سخن گوید، مانند اقوال خدا بگوید و اگر کسی خدمت کند، برحسب توانایی که خدا بدو داده باشد بکند تا در همه‌چیز، خدا بواسطه عیسی مسیح جلال یابد که او را جلال و توانایی تاابدالاباد هست، آمین."},{"v":12,"t":"‌ای حبیبان، تعجب منمایید از این آتشی که در میان شماست و بجهت امتحان شما می‌آید که گویا چیزی غریب بر شما واقع شده باشد."},{"v":13,"t":"بلکه بقدری که شریک زحمات مسیح هستید، خشنودشوید تا در هنگام ظهور جلال وی شادی و وجدنمایید."},{"v":14,"t":"اگر بخاطر نام مسیح رسوایی می‌کشید، خوشابحال شما زیرا که روح جلال وروح خدا بر شما آرام می‌گیرد."},{"v":15,"t":"پس زنهار هیچ‌یکی از شما چون قاتل یا دزد یا شریر یا فضول عذاب نکشد."},{"v":16,"t":"لکن اگر چون مسیحی عذاب بکشد، پس شرمنده نشود بلکه به این اسم خدا راتمجید نماید."},{"v":17,"t":"زیرا این زمان است که داوری ازخانه خدا شروع شود؛ و اگر شروع آن از ماست، پس عاقبت کسانی که انجیل خدا را اطاعت نمی کنند چه خواهد شد؟"},{"v":18,"t":"و اگر عادل به دشواری نجات یابد، بی‌دین و گناهکار کجا یافت خواهد شد؟"},{"v":19,"t":"پس کسانی نیز که برحسب اراده خدا زحمت کشند، جانهای خود را در نیکوکاری به خالق امین بسپارند."}],"en":[{"v":1,"t":"Therefore, since Christ suffered for us in the flesh, arm yourselves also with the same mind; for he who has suffered in the flesh has ceased from sin,"},{"v":2,"t":"that you no longer should live the rest of your time in the flesh for the lusts of men, but for the will of God."},{"v":3,"t":"For we have spent enough of our past time doing the desire of the Gentiles, and having walked in lewdness, lusts, drunken binges, orgies, carousings, and abominable idolatries."},{"v":4,"t":"They think it is strange that you don’t run with them into the same excess of riot, speaking evil of you."},{"v":5,"t":"They will give account to him who is ready to judge the living and the dead."},{"v":6,"t":"For to this end the Good News was preached even to the dead, that they might be judged indeed as men in the flesh, but live as to God in the spirit."},{"v":7,"t":"But the end of all things is near. Therefore be of sound mind, self-controlled, and sober in prayer."},{"v":8,"t":"And above all things be earnest in your love among yourselves, for love covers a multitude of sins."},{"v":9,"t":"Be hospitable to one another without grumbling."},{"v":10,"t":"As each has received a gift, employ it in serving one another, as good managers of the grace of God in its various forms."},{"v":11,"t":"If anyone speaks, let it be as it were the very words of God. If anyone serves, let it be as of the strength which God supplies, that in all things God may be glorified through Jesus Christ, to whom belong the glory and the dominion forever and ever. Amen."},{"v":12,"t":"Beloved, don’t be astonished at the fiery trial which has come upon you to test you, as though a strange thing happened to you."},{"v":13,"t":"But because you are partakers of Christ’s sufferings, rejoice, that at the revelation of his glory you also may rejoice with exceeding joy."},{"v":14,"t":"If you are insulted for the name of Christ, you are blessed, because the Spirit of glory and of God rests on you. On their part he is blasphemed, but on your part he is glorified."},{"v":15,"t":"But let none of you suffer as a murderer, or a thief, or an evil doer, or a meddler in other men’s matters."},{"v":16,"t":"But if one of you suffers for being a Christian, let him not be ashamed; but let him glorify God in this matter."},{"v":17,"t":"For the time has come for judgment to begin with the household of God. If it begins first with us, what will happen to those who don’t obey the Good News of God?"},{"v":18,"t":"“If it is hard for the righteous to be saved, what will happen to the ungodly and the sinner?”"},{"v":19,"t":"Therefore let them also who suffer according to the will of God in doing good entrust their souls to him, as to a faithful Creator."}],"hr":[{"v":1,"t":"Dakle, budući da je Krist trpio u tijelu, i vi se oboružajte istim mišljenjem - jer tko trpi u tijelu okanio se grijeha -"},{"v":2,"t":"da vrijeme što vam u tijelu još preostaje proživite ne više po ljudskim požudama nego po Božjoj volji."},{"v":3,"t":"Dosta je uistinu što ste u prošlom vremenu vršili volju pogana, hodeći u razvratnostima, požudama, pijančevanjima, pijankama, opijanjima i bezakoničkim idolopoklonstvima."},{"v":4,"t":"Stoga se čude što se ne slijevate u tu istu rijeku raskalašenosti te proklinju."},{"v":5,"t":"Polagat će oni račun Onomu tko je već spreman suditi žive i mrtve."},{"v":6,"t":"Zato je i mrtvima naviješteno evanđelje da osuđeni doduše po ljudsku, u tijelu, žive po Božju - u duhu."},{"v":7,"t":"Približio se svršetak svega! Osvijestite se i otrijeznite za molitvu!"},{"v":8,"t":"Prije svega imajte žarku ljubav jedni prema drugima jer ljubav pokriva mnoštvo grijeha!"},{"v":9,"t":"Gostoljubivo primajte jedni druge bez mrmljanja!"},{"v":10,"t":"Jedni druge poslužujte - svatko po primljenom daru - kao dobri upravitelji različitih Božjih milosti!"},{"v":11,"t":"Govori li tko? Neka govori kao riječi Božje! Poslužuje li tko? Neka poslužuje kao snagom koju daje Bog da se u svemu slavi Bog po Isusu Kristu, komu slava i vlast u vijeke vijekova! Amen."},{"v":12,"t":"Ljubljeni! Ne čudite se požaru što bukti među vama da vas iskuša, kao da vam se događa štogod neobično!"},{"v":13,"t":"Naprotiv, radujte se kao zajedničari Kristovih patnja da i o Objavljenju njegove slave mognete radosno klicati."},{"v":14,"t":"Pogrđuju li vas zbog imena Kristova, blago vama, jer Duh Slave, Duh Božji u vama počiva."},{"v":15,"t":"Tek neka nitko od vas ne trpi kao ubojica, ili kradljivac, ili zločinac, ili makar i kao nametljivac;"},{"v":16,"t":"ako li kao kršćanin, neka se ne stidi, nego slavi Boga zbog tog imena."},{"v":17,"t":"Ta vrijeme je da započne Sud - od doma Božjega. No ako već od vas započinje, kakav je onda svršetak onih što nisu poslušni Božjem evanđelju?"},{"v":18,"t":"I ako se pravednik jedva spasava, opak i grešnik gdje da se pojavi?"},{"v":19,"t":"Stoga oni koji po volji Božjoj trpe, neka dobrim djelima povjere duše svoje vjernom Stvoritelju."}]},"5":{"fa":[{"v":1,"t":"پیران را در میان شما نصیحت می‌کنم، من که نیز با شما پیر هستم و شاهد بر زحمات مسیح و شریک در جلالی که مکشوف خواهدشد."},{"v":2,"t":"گله خدا را که در میان شماست بچرانید ونظارت آن را بکنید، نه به زور بلکه به رضامندی ونه بجهت سود قبیح بلکه به رغبت؛"},{"v":3,"t":"و نه‌چنانکه بر قسمت های خود خداوندی بکنید بلکه بجهت گله نمونه باشید،"},{"v":4,"t":"تا در وقتی که رئیس شبانان ظاهر شود، تاج ناپژمرده جلال را بیابید."},{"v":5,"t":"همچنین‌ای جوانان، مطیع پیران باشید بلکه همه با یکدیگر فروتنی را بر خود ببندید زیرا خدابا متکبران مقاومت می‌کند و فروتنان را فیض می‌بخشد."},{"v":6,"t":"پس زبردست زورآور خدا فروتنی نمایید تا شما را در وقت معین سرافراز نماید."},{"v":7,"t":"وتمام اندیشه خود را به وی واگذارید زیرا که اوبرای شما فکر می‌کند."},{"v":8,"t":"هشیار و بیدار باشید زیراکه دشمن شما ابلیس مانند شیر غران گردش می‌کند و کسی را می‌طلبد تا ببلعد."},{"v":9,"t":"پس به ایمان استوار شده، با او مقاومت کنید، چون آگاه هستیدکه همین زحمات بر برادران شما که در دنیاهستند، می‌آید."},{"v":10,"t":"و خدای همه فیضها که ما را به جلال ابدی خود در عیسی مسیح خوانده، است، شما را بعداز کشیدن زحمتی قلیل کامل و استوار و تواناخواهد ساخت."},{"v":11,"t":"او را تا ابدالاباد جلال وتوانایی باد، آمین."},{"v":12,"t":"به توسط سلوانس که او را برادر امین شمامی شمارم، مختصری نوشتم و نصیحت وشهادت می‌دهم که همین است فیض حقیقی خداکه بر آن قائم هستید."},{"v":13,"t":"خواهر برگزیده با شما که در بابل است و پسر من مرقس به شما سلام می‌رسانند."},{"v":14,"t":"یکدیگر را به بوسه محبتانه سلام نمایید و همه شما را که در مسیح عیسی هستید، سلام باد آمین."}],"en":[{"v":1,"t":"Therefore I exhort the elders among you, as a fellow elder and a witness of the sufferings of Christ, and who will also share in the glory that will be revealed:"},{"v":2,"t":"shepherd the flock of God which is among you, exercising the oversight, not under compulsion, but voluntarily; not for dishonest gain, but willingly;"},{"v":3,"t":"not as lording it over those entrusted to you, but making yourselves examples to the flock."},{"v":4,"t":"When the chief Shepherd is revealed, you will receive the crown of glory that doesn’t fade away."},{"v":5,"t":"Likewise, you younger ones, be subject to the elder. Yes, all of you clothe yourselves with humility and subject yourselves to one another; for “God resists the proud, but gives grace to the humble.”"},{"v":6,"t":"Humble yourselves therefore under the mighty hand of God, that he may exalt you in due time,"},{"v":7,"t":"casting all your worries on him, because he cares for you."},{"v":8,"t":"Be sober and self-controlled. Be watchful. Your adversary, the devil, walks around like a roaring lion, seeking whom he may devour."},{"v":9,"t":"Withstand him steadfast in your faith, knowing that your brothers who are in the world are undergoing the same sufferings."},{"v":10,"t":"But may the God of all grace, who called you to his eternal glory by Christ Jesus, after you have suffered a little while, perfect, establish, strengthen, and settle you."},{"v":11,"t":"To him be the glory and the power forever and ever. Amen."},{"v":12,"t":"Through Silvanus, our faithful brother, as I consider him, I have written to you briefly, exhorting and testifying that this is the true grace of God in which you stand."},{"v":13,"t":"She who is in Babylon, chosen together with you, greets you. So does Mark, my son."},{"v":14,"t":"Greet one another with a kiss of love. Peace be to all of you who are in Christ Jesus. Amen."}],"hr":[{"v":1,"t":"Starješine dakle među vama opominjem, ja sustarješina i svjedok Kristovih patnja, a zato i zajedničar slave koja se ima očitovati:"},{"v":2,"t":"pasite povjereno vam stado Božje, nadgledajte ga - ne prisilno, nego dragovoljno, po Božju; ne radi prljava dobitka, nego oduševljeno;"},{"v":3,"t":"i ne kao gospodari Baštine nego kao uzori stada."},{"v":4,"t":"Pa kad se pojavi Natpastir, primit ćete neuveli vijenac slave."},{"v":5,"t":"Tako i vi, mladići, podložite se starješinama; svi se jedni prema drugima pripašite poniznošću jer Bog se oholima protivi, a poniznima daruje milost."},{"v":6,"t":"Ponizite se dakle pod snažnom rukom Božjom da vas uzvisi u pravo vrijeme."},{"v":7,"t":"Svu svoju brigu povjerite njemu jer on se brine za vas."},{"v":8,"t":"Otrijeznite se! Bdijte! Protivnik vaš, đavao, kao ričući lav obilazi tražeći koga da proždre."},{"v":9,"t":"Oprite mu se stameni u vjeri znajući da takve iste patnje podnose vaša braća po svijetu."},{"v":10,"t":"A Bog svake milosti, koji vas pozva na vječnu slavu u Kristu, on će vas, pošto malo potrpite, usavršiti, učvrstiti, ojačati, utvrditi."},{"v":11,"t":"Njemu vlast u vijeke vjekova! Amen."},{"v":12,"t":"Pišem vam ukratko, po Silvanu, koga smatram bratom vjernim, da vas ohrabrim i posvjedočim kako je ovo istinska milost Božja. Nje se držite!"},{"v":13,"t":"Pozdravlja vas suizabranica u Babilonu i Marko, sin moj."},{"v":14,"t":"Pozdravite jedni druge cjelovom ljubavi! Mir svima vama koji ste u Kristu!"}]}},"2PE":{"1":{"fa":[{"v":1,"t":"شمعون پطرس، غلام و رسول عیسی مسیح، به آنانی که ایمان گرانبها را به مساوی مایافته‌اند، در عدالت خدای ما و عیسی مسیح نجات‌دهنده."},{"v":2,"t":"فیض و سلامتی در معرفت خدا و خداوند ماعیسی بر شما افزون باد."},{"v":3,"t":"چنانکه قوت الهیه او همه‌چیزهایی را که برای حیات و دینداری لازم است، به ما عنایت فرموده است، به معرفت او که ما را به جلال وفضیلت خود دعوت نموده،"},{"v":4,"t":"که بوساطت آنهاوعده های بینهایت عظیم و گرانبها به ما داده شد تاشما به اینها شریک طبیعت الهی گردید و ازفسادی که از شهوت در جهان است، خلاصی یابید."},{"v":5,"t":"و به همین جهت، کمال سعی نموده، درایمان خود فضیلت پیدا نمایید"},{"v":6,"t":"و در فضیلت، علم و در علم، عفت و در عفت، صبر و در صبر، دینداری"},{"v":7,"t":"و در دینداری، محبت برادران و درمحبت برادران، محبت را."},{"v":8,"t":"زیرا هرگاه اینها درشما یافت شود و بیفزاید، شما را نمی گذارد که درمعرفت خداوند ما عیسی مسیح کاهل یا بی‌ثمربوده باشید."},{"v":9,"t":"زیرا هرکه اینها را ندارد، کور وکوتاه نظر است و تطیهر گناهان گذشته خود را فراموش کرده است."},{"v":10,"t":"لهذا‌ای برادران بیشتر جد و جهد کنید تادعوت و برگزیدگی خود را ثابت نمایید زیرا اگرچنین کنید هرگز لغزش نخواهید خورد."},{"v":11,"t":"وهمچنین دخول در ملکوت جاودانی خداوند ونجات‌دهنده ما عیسی مسیح به شما به دولتمندی داده خواهد شد."},{"v":12,"t":"لهذا از پیوسته یاد دادن شما از این امورغفلت نخواهم ورزید، هرچند آنها را می‌دانید ودر آن راستی که نزد شما است استوار هستید."},{"v":13,"t":"لکن این را صواب می‌دانم، مادامی که در این خیمه هستم، شما را به یاد آوری برانگیزانم."},{"v":14,"t":"چونکه می‌دانم که وقت بیرون کردن خیمه من نزدیک است، چنانکه خداوند ما عیسی مسیح نیزمرا آگاهانید."},{"v":15,"t":"و برای این نیز کوشش می‌کنم تاشما در هروقت بعد از رحلت من، بتوانید این اموررا یاد آورید."},{"v":16,"t":"زیرا که در‌پی افسانه های جعلی نرفتیم، چون از قوت و آمدن خداوند ما عیسی مسیح شما را اعلام دادیم، بلکه کبریایی او رادیده بودیم."},{"v":17,"t":"زیرا از خدای پدر اکرام و جلال یافت هنگامی که آوازی از جلال کبریایی به اورسید که «این است پسر حبیب من که از وی خشنودم.»"},{"v":18,"t":"و این آواز را ما زمانی که با وی درکوه مقدس بودیم، شنیدیم که از آسمان آورده شد."},{"v":19,"t":"و کلام انبیا را نیز محکم تر داریم که نیکومی کنید اگر در آن اهتمام کنید، مثل چراغی درخشنده در مکان تاریک تا روز بشکافد و ستاره صبح در دلهای شما طلوع کند."},{"v":20,"t":"و این رانخست بدانید که هیچ نبوت کتاب از تفسیر خودنبی نیست."},{"v":21,"t":"زیرا که نبوت به اراده انسان هرگزآورده نشد، بلکه مردمان به روح‌القدس مجذوب شده، از جانب خدا سخن‌گفتند."}],"en":[{"v":1,"t":"Simon Peter, a servant and apostle of Jesus Christ, to those who have obtained a like precious faith with us in the righteousness of our God and Savior, Jesus Christ:"},{"v":2,"t":"Grace to you and peace be multiplied in the knowledge of God and of Jesus our Lord,"},{"v":3,"t":"seeing that his divine power has granted to us all things that pertain to life and godliness, through the knowledge of him who called us by his own glory and virtue,"},{"v":4,"t":"by which he has granted to us his precious and exceedingly great promises; that through these you may become partakers of the divine nature, having escaped from the corruption that is in the world by lust."},{"v":5,"t":"Yes, and for this very cause adding on your part all diligence, in your faith supply moral excellence; and in moral excellence, knowledge;"},{"v":6,"t":"and in knowledge, self-control; and in self-control, perseverance; and in perseverance, godliness;"},{"v":7,"t":"and in godliness, brotherly affection; and in brotherly affection, love."},{"v":8,"t":"For if these things are yours and abound, they make you to not be idle or unfruitful in the knowledge of our Lord Jesus Christ."},{"v":9,"t":"For he who lacks these things is blind, seeing only what is near, having forgotten the cleansing from his old sins."},{"v":10,"t":"Therefore, brothers, be more diligent to make your calling and election sure. For if you do these things, you will never stumble."},{"v":11,"t":"For thus you will be richly supplied with the entrance into the eternal Kingdom of our Lord and Savior, Jesus Christ."},{"v":12,"t":"Therefore I will not be negligent to remind you of these things, though you know them and are established in the present truth."},{"v":13,"t":"I think it right, as long as I am in this tent, to stir you up by reminding you,"},{"v":14,"t":"knowing that the putting off of my tent comes swiftly, even as our Lord Jesus Christ made clear to me."},{"v":15,"t":"Yes, I will make every effort that you may always be able to remember these things even after my departure."},{"v":16,"t":"For we didn’t follow cunningly devised fables when we made known to you the power and coming of our Lord Jesus Christ, but we were eyewitnesses of his majesty."},{"v":17,"t":"For he received from God the Father honor and glory when the voice came to him from the Majestic Glory, “This is my beloved Son, in whom I am well pleased.”"},{"v":18,"t":"We heard this voice come out of heaven when we were with him on the holy mountain."},{"v":19,"t":"We have the more sure word of prophecy; and you do well that you heed it as to a lamp shining in a dark place, until the day dawns and the morning star arises in your hearts,"},{"v":20,"t":"knowing this first, that no prophecy of Scripture is of private interpretation."},{"v":21,"t":"For no prophecy ever came by the will of man, but holy men of God spoke, being moved by the Holy Spirit."}],"hr":[{"v":1,"t":"Šimun Petar, sluga i apostol Isusa Krista, onima koje pravednošću Boga našega i Spasitelja Isusa Krista zapade ista dragocjena vjera kao i nas."},{"v":2,"t":"Punina vam milosti i mira po spoznaji Boga i Isusa, Gospodina našega!"},{"v":3,"t":"Doista, po spoznaji njega, koji nas pozva slavom svojom i krepošću, božanska nas je snaga njegova obdarila svime za život i pobožnost."},{"v":4,"t":"Time smo obdareni dragocjenim, najvećim obećanjima da po njima postanete zajedničari božanske naravi umakavši pokvarenosti koja je u svijetu zbog požude."},{"v":5,"t":"Zbog toga svim marom prionite: vjerom osigurajte krepost, krepošću spoznaje,"},{"v":6,"t":"spoznanjem uzdržljivost, uzdržljivošću postojanost, postojanošću pobožnost,"},{"v":7,"t":"pobožnošću bratoljublje, bratoljubljem ljubav."},{"v":8,"t":"Jer ako to imate i u tom napredujete, nećete biti besposleni i neplodni za spoznanje Isusa Krista."},{"v":9,"t":"A tko toga nema, slijep je, kratkovidan; zaboravio je da je očišćen od svojih prijašnjih grijeha."},{"v":10,"t":"Zato, braćo, to revnije uznastojte učvrstiti svoj poziv i izabranje: to čineći - ne, nećete posrnuti nikada!"},{"v":11,"t":"Tako će vam se bogato osigurati ulazak u vječno kraljevstvo Gospodina našega i Spasitelja Isusa Krista."},{"v":12,"t":"Zato ću vas uvijek na to podsjećati premda to znate i utvrđeni ste u primljenoj istini."},{"v":13,"t":"Pravo je, mislim, da vas dok sam u ovom šatoru, budim opomenom,"},{"v":14,"t":"svjestan da ću brzo napustiti svoj šator, kako mi i Gospodin naš Isus Krist očitova."},{"v":15,"t":"A pobrinut ću se da se i nakon mojeg izlaska uvijek toga sjećate."},{"v":16,"t":"Ta nismo vam navijestili snagu i Dolazak Gospodina našega Isusa Krista slijedeći izmudrene priče, nego kao očevici njegova veličanstva."},{"v":17,"t":"Od Oca je doista primio čast i slavu kad mu ono od uzvišene Slave doprije ovaj glas: Ovo je Sin moj, Ljubljeni moj, u njemu mi sva milina!"},{"v":18,"t":"Taj glas, koji s neba dopiraše, čusmo mi koji bijasmo s njime na Svetoj gori."},{"v":19,"t":"Tako nam je potvrđena proročka riječ te dobro činite što uza nju prianjate kao uza svjetiljku što svijetli na mrklu mjestu - dok Dan ne osvane i Danica se ne pomoli u srcima vašim."},{"v":20,"t":"Ponajprije znajte ovo: nijedno se proroštvo Pisma ne može tumačiti samovoljno"},{"v":21,"t":"jer nikada proroštvo ne bi ljudskom voljom doneseno, nego su Duhom Svetim poneseni ljudi od Boga govorili."}]},"2":{"fa":[{"v":1,"t":"لکن در میان قوم، انبیای کذبه نیز بودند، چنانکه در میان شما هم معلمان کذبه خواهند بود که بدعتهای مهلک را خفیه خواهندآورد و آن آقایی را که ایشان را خرید انکارخواهند نمود و هلاکت سریع را بر خود خواهندکشید؛"},{"v":2,"t":"و بسیاری فجور ایشان را متابعت خواهند نمود که به‌سبب ایشان طریق حق، موردملامت خواهد شد."},{"v":3,"t":"و از راه طمع به سخنان جعلی شما را خرید و فروش خواهند کرد که عقوبت ایشان از مدت مدید تاخیر نمی کند وهلاکت ایشان خوابیده نیست."},{"v":4,"t":"زیرا هرگاه خدا بر فرشتگانی که گناه کردند، شفقت ننمود بلکه ایشان را به جهنم انداخته، به زنجیرهای ظلمت سپرد تا برای داوری نگاه داشته شوند؛"},{"v":5,"t":"و بر عالم قدیم شفقت نفرمود بلکه نوح، واعظ عدالت را با هفت نفر دیگر محفوظداشته، طوفان را بر عالم بی‌دینان آورد؛"},{"v":6,"t":"وشهرهای سدوم و عموره را خاکستر نموده، حکم به واژگون شدن آنها فرمود و آنها را برای آنانی که بعد از این بی‌دینی خواهند کرد، عبرتی ساخت؛"},{"v":7,"t":"و لوط عادل را که از رفتار فاجرانه بی‌دینان رنجیده بود رهانید."},{"v":8,"t":"زیرا که آن مرد عادل درمیانشان ساکن بوده، از آنچه می‌دید و می‌شنید، دل صالح خود را به‌کارهای قبیح ایشان هرروزه رنجیده می‌داشت."},{"v":9,"t":"پس خداوند می‌داند که عادلان را از تجربه رهایی دهد و ظالمان را تا به روز جزا در عذاب نگاه دارد."},{"v":10,"t":"خصوص آنانی که در شهوات نجاست در‌پی جسم می‌روند وخداوندی را حقیر می‌دانند."},{"v":11,"t":"و حال آنکه فرشتگانی که در قدرت و قوت افضل هستند، پیش خداوند برایشان حکم افترا نمی زنند."},{"v":12,"t":"لکن اینها چون حیوانات غیرناطق که برای صید و هلاکت طبع متولد شده‌اند، ملامت می‌کنند بر آنچه نمی دانندو در فساد خود هلاک خواهند شد."},{"v":13,"t":"و مزدناراستی خود را خواهند یافت که عیش و عشرت یک روزه را سرور خود می‌دانند. لکه‌ها و عیبهاهستند که در ضیافت های محبتانه خود عیش وعشرت می‌نمایند وقتی که با شما شادی می‌کنند."},{"v":14,"t":"چشمهای پر از زنا دارند که از گناه بازداشته نمی شود، و کسان ناپایدار را به دام می‌کشند؛ ابنای لعنت که قلب خود را برای طمع ریاضت داده‌اند،"},{"v":15,"t":"و راه مستقیم را ترک کرده، گمراه شدند و طریق بلعام بن بصور را که مزد ناراستی رادوست می‌داشت، متابعت کردند."},{"v":16,"t":"لکن او ازتقصیر خود توبیخ یافت که حمار گنگ به زبان انسان متنطق شده، دیوانگی نبی را توبیخ نمود."},{"v":17,"t":"اینها چشمه های بی‌آب و مه های رانده شده به باد شدید هستند که برای ایشان ظلمت تاریکی جاودانی، مقرر است."},{"v":18,"t":"زیرا که سخنان تکبرآمیز و باطل می‌گویند و آنانی را که از اهل ضلالت تازه رستگار شده‌اند، در دام شهوات به فجور جسمی می‌کشند،"},{"v":19,"t":"و ایشان را به آزادی وعده می‌دهند و حال آنکه خود غلام فسادهستند، زیرا هرچیزی که بر کسی غلبه یافته باشد، او نیز غلام آن است."},{"v":20,"t":"زیرا هرگاه به معرفت خداوند و نجات‌دهنده ما عیسی مسیح ازآلایش دنیوی رستند و بعد از آن، بار دیگر گرفتارو مغلوب آن گشتند، اواخر ایشان از اوایل بدترمی شود."},{"v":21,"t":"زیرا که برای ایشان بهتر می‌بود که راه عدالت را ندانسته باشند از اینکه بعد از دانستن باردیگر از آن حکم مقدس که بدیشان سپرده شده بود، برگردند."},{"v":22,"t":"لکن معنی مثل حقیقی بر ایشان راست آمد که «سگ به قی خود رجوع کرده است و خنزیر شسته شده، به غلطیدن در گل.»"}],"en":[{"v":1,"t":"But false prophets also arose among the people, as false teachers will also be among you, who will secretly bring in destructive heresies, denying even the Master who bought them, bringing on themselves swift destruction."},{"v":2,"t":"Many will follow their immoral ways, and as a result, the way of the truth will be maligned."},{"v":3,"t":"In covetousness they will exploit you with deceptive words: whose sentence now from of old doesn’t linger, and their destruction will not slumber."},{"v":4,"t":"For if God didn’t spare angels when they sinned, but cast them down to Tartarus, and committed them to pits of darkness to be reserved for judgment;"},{"v":5,"t":"and didn’t spare the ancient world, but preserved Noah with seven others, a preacher of righteousness, when he brought a flood on the world of the ungodly,"},{"v":6,"t":"and turning the cities of Sodom and Gomorrah into ashes, condemned them to destruction, having made them an example to those who would live in an ungodly way,"},{"v":7,"t":"and delivered righteous Lot, who was very distressed by the lustful life of the wicked"},{"v":8,"t":"(for that righteous man dwelling among them was tormented in his righteous soul from day to day with seeing and hearing lawless deeds),"},{"v":9,"t":"then the Lord knows how to deliver the godly out of temptation and to keep the unrighteous under punishment for the day of judgment,"},{"v":10,"t":"but chiefly those who walk after the flesh in the lust of defilement and despise authority. Daring, self-willed, they are not afraid to speak evil of dignitaries,"},{"v":11,"t":"whereas angels, though greater in might and power, don’t bring a slanderous judgment against them before the Lord."},{"v":12,"t":"But these, as unreasoning creatures, born natural animals to be taken and destroyed, speaking evil in matters about which they are ignorant, will in their destroying surely be destroyed,"},{"v":13,"t":"receiving the wages of unrighteousness; people who count it pleasure to revel in the daytime, spots and defects, reveling in their deceit while they feast with you;"},{"v":14,"t":"having eyes full of adultery, and who can’t cease from sin, enticing unsettled souls, having a heart trained in greed, accursed children!"},{"v":15,"t":"Forsaking the right way, they went astray, having followed the way of Balaam the son of Beor, who loved the wages of wrongdoing;"},{"v":16,"t":"but he was rebuked for his own disobedience. A speechless donkey spoke with a man’s voice and stopped the madness of the prophet."},{"v":17,"t":"These are wells without water, clouds driven by a storm, for whom the blackness of darkness has been reserved forever."},{"v":18,"t":"For, uttering great swelling words of emptiness, they entice in the lusts of the flesh, by licentiousness, those who are indeed escaping from those who live in error;"},{"v":19,"t":"promising them liberty, while they themselves are bondservants of corruption; for a man is brought into bondage by whoever overcomes him."},{"v":20,"t":"For if, after they have escaped the defilement of the world through the knowledge of the Lord and Savior Jesus Christ, they are again entangled in it and overcome, the last state has become worse for them than the first."},{"v":21,"t":"For it would be better for them not to have known the way of righteousness, than after knowing it, to turn back from the holy commandment delivered to them."},{"v":22,"t":"But it has happened to them according to the true proverb, “The dog turns to his own vomit again,” and “the sow that has washed to wallowing in the mire.”"}],"hr":[{"v":1,"t":"Bilo je u narodu i lažnih proroka, kao što će i među vama biti lažnih učitelja, onih koji će prokrijumčariti pogubna krivovjerja, zanijekati Gospodina koji ih otkupi, i navući na se brzu propast."},{"v":2,"t":"I mnogi će se povesti za njihovim razvratnostima. Zbog njih će se kuditi put istine."},{"v":3,"t":"U svojoj će vas lakomosti kupovati izmišljotinama. Njihova osuda već odavna nije dokona i propast im ne drijema."},{"v":4,"t":"Doista, ako Bog anđela koji sagriješiše nije poštedio nego ih je sunovratio u Tartar i predao mračnom bezdanu da budu čuvani za sud;"},{"v":5,"t":"ako staroga svijeta ne poštedje, nego sačuva - osmoga - Nou, glasnika pravednosti, sručivši potop na svijet bezbožni;"},{"v":6,"t":"ako gradove Sodomu i Gomoru u pepeo pretvori, osudi i za primjer budućim bezbožnicima postavi;"},{"v":7,"t":"ako pravednog Lota, premorena razvratnim življenjem onih razularenika, oslobodi -"},{"v":8,"t":"pravedniku se doista dan za danom duša razdirala dok je gledao i slušao bezakonička djela onih među kojima je boravio -"},{"v":9,"t":"umije Gospod i pobožnike iz napasti izbaviti, a nepravednike za kaznu na Dan sudnji sačuvati,"},{"v":10,"t":"ponajpače one koji u prljavoj požudi idu za puti i preziru Veličanstvo. Preuzetnici, drznici i ne trepnu pogrđujući Slave,"},{"v":11,"t":"dok anđeli, iako jakošću i snagom od njih veći, ne izriču protiv njih pred Gospodinom pogrdna suda."},{"v":12,"t":"Oni pak kao nerazumne životinje, po naravi rođene za lov i istrebljenje, pogrđuju što ne poznaju. Istim će istrebljenjem i oni biti istrebljeni;"},{"v":13,"t":"zadesit će ih nepravda, plaća nepravednosti. Užitkom smatraju razvratnost u pol bijela dana. Ljage i sramote! Naslađuju se prijevarama svojim dok se s vama goste."},{"v":14,"t":"Oči su im pune preljubnice, nikako da se nasite grijeha; mame duše nepostojane, srce im je uvježbano u lakomstvu, prokleti sinovi!"},{"v":15,"t":"Zabludiše, napustivši ravan put, te pođoše putom Bosorova sina Bileama, koji prigrli plaću nepravednosti,"},{"v":16,"t":"ali primi i ukor za svoje nedjelo: nijemo živinče ljudskim glasom prozbori i spriječi prorokovo bezumlje."},{"v":17,"t":"Oni su izvori bezvodni, oblaci vjetrom gonjeni; za njih se čuva mrkla tmina."},{"v":18,"t":"Naklapajući naduvene ispraznosti, požudama putenim, razvratnostima mame one što netom odbjegoše od onih koji žive u zabludi."},{"v":19,"t":"Obećavaju im slobodu, a sami su robovi pokvarenosti. Jer svatko robuje onomu tko ga svlada."},{"v":20,"t":"Doista, pošto su po spoznaji Gospodina našega i Spasitelja Isusa Krista odbjegli od prljavština svijeta, ako se opet u njih upleću i daju se svladati, ovo im je potonje gore od onoga prvoga."},{"v":21,"t":"Bilo bi im doista bolje da nisu spoznali puta pravednosti, negoli, pošto ga spoznaše, okrenuti leđa svetoj zapovijedi koja im je predana."},{"v":22,"t":"Dogodilo im se što veli istinita izreka: “Pas se vraća svojoj bljuvotini i okupana svinja valjanju u blatu.”"}]},"3":{"fa":[{"v":1,"t":"این رساله دوم را‌ای حبیبان الان به شمامی نویسم که به این هردو، دل پاک شما را به طریق یادگاری برمی انگیزانم،"},{"v":2,"t":"تا بخاطر آریدکلماتی که انبیای مقدس، پیش گفته‌اند و حکم خداوند و نجات‌دهنده را که به رسولان شما داده شد."},{"v":3,"t":"و نخست این را می‌دانید که در ایام آخرمستهزئین با استهزا ظاهر خواهند شد که بر وفق شهوات خود رفتار نموده،"},{"v":4,"t":"خواهند گفت: «کجاست وعده آمدن او؟ زیرا از زمانی که پدران به خواب رفتند، هرچیز به همینطوری که ازابتدای آفرینش بود، باقی است.»"},{"v":5,"t":"زیرا که ایشان عمد از این غافل هستند که به کلام خدا آسمانهااز قدیم بود و زمین از آب و به آب قائم گردید."},{"v":6,"t":"وبه این هردو، عالمی که آن وقت بود در آب غرق شده، هلاک گشت."},{"v":7,"t":"لکن آسمان و زمین الان به همان کلام برای آتش ذخیره شده و تا روز داوری و هلاکت، مردم بی‌دین نگاه داشته شده‌اند."},{"v":8,"t":"لکن‌ای حبیبان، این یک چیز از شما مخفی نماند که یک روز نزد خدا چون هزار سال است وهزار سال چون یک روز."},{"v":9,"t":"خداوند در وعده خودتاخیر نمی نماید چنانکه بعضی تاخیرمی پندارند، بلکه بر شما تحمل می‌نماید چون نمی خواهد که کسی هلاک گردد بلکه همه به توبه گرایند."},{"v":10,"t":"لکن روز خداوند چون دزد خواهدآمد که در آن آسمانها به صدای عظیم زایل خواهند شد و عناصر سوخته شده، از هم خواهدپاشید و زمین و کارهایی که در آن است سوخته خواهد شد."},{"v":11,"t":"پس چون جمیع اینها متفرق خواهندگردید، شما چطور مردمان باید باشید، در هرسیرت مقدس و دینداری؟"},{"v":12,"t":"و آمدن روز خدارا انتظار بکشید و آن را بشتابانید که در آن آسمانها سوخته شده، از هم متفرق خواهند شد وعناصر از حرارت گداخته خواهد گردید."},{"v":13,"t":"ولی بحسب وعده او، منتظر آسمانهای جدید و زمین جدید هستیم که در آنها عدالت ساکن خواهد بود."},{"v":14,"t":"لهذا‌ای حبیبان، چون انتظار این چیزها رامی کشید، جد و جهد نمایید تا نزد او بی‌داغ و بی عیب در سلامتی یافت شوید."},{"v":15,"t":"و تحمل خداوند ما را نجات بدانید، چنانکه برادر حبیب ماپولس نیز برحسب حکمتی که به وی داده شد، به شما نوشت."},{"v":16,"t":"و همچنین در سایر رساله های خود این چیزها را بیان می‌نماید که در آنها بعضی چیزهاست که فهمیدن آنها مشکل است و مردمان بی‌علم و ناپایدار آنها را مثل سایر کتب تحریف می کنند تا به هلاکت خود برسند."},{"v":17,"t":"پس شما‌ای حبیبان، چون این امور را ازپیش می‌دانید، باحذر باشید که مبادا به گمراهی بی‌دینان ربوده شده، از پایداری خود بیفتید."},{"v":18,"t":"بلکه در فیض و معرفت خداوند و نجات‌دهنده ما عیسی مسیح ترقی کنید، که او را از کنون تاابدالاباد جلال باد. آمین."}],"en":[{"v":1,"t":"This is now, beloved, the second letter that I have written to you; and in both of them I stir up your sincere mind by reminding you"},{"v":2,"t":"that you should remember the words which were spoken before by the holy prophets and the commandment of us, the apostles of the Lord and Savior,"},{"v":3,"t":"knowing this first, that in the last days mockers will come, walking after their own lusts"},{"v":4,"t":"and saying, “Where is the promise of his coming? For, from the day that the fathers fell asleep, all things continue as they were from the beginning of the creation.”"},{"v":5,"t":"For they willfully forget that there were heavens from of old, and an earth formed out of water and amid water by the word of God,"},{"v":6,"t":"by which means the world that existed then, being overflowed with water, perished."},{"v":7,"t":"But the heavens that exist now and the earth, by the same word have been stored up for fire, being reserved against the day of judgment and destruction of ungodly men."},{"v":8,"t":"But don’t forget this one thing, beloved, that one day is with the Lord as a thousand years, and a thousand years as one day."},{"v":9,"t":"The Lord is not slow concerning his promise, as some count slowness; but he is patient with us, not wishing that anyone should perish, but that all should come to repentance."},{"v":10,"t":"But the day of the Lord will come as a thief in the night, in which the heavens will pass away with a great noise, and the elements will be dissolved with fervent heat; and the earth and the works that are in it will be burned up."},{"v":11,"t":"Therefore, since all these things will be destroyed like this, what kind of people ought you to be in holy living and godliness,"},{"v":12,"t":"looking for and earnestly desiring the coming of the day of God, which will cause the burning heavens to be dissolved, and the elements will melt with fervent heat?"},{"v":13,"t":"But, according to his promise, we look for new heavens and a new earth, in which righteousness dwells."},{"v":14,"t":"Therefore, beloved, seeing that you look for these things, be diligent to be found in peace, without defect and blameless in his sight."},{"v":15,"t":"Regard the patience of our Lord as salvation; even as our beloved brother Paul also, according to the wisdom given to him, wrote to you,"},{"v":16,"t":"as also in all of his letters, speaking in them of these things. In those, there are some things that are hard to understand, which the ignorant and unsettled twist, as they also do to the other Scriptures, to their own destruction."},{"v":17,"t":"You therefore, beloved, knowing these things beforehand, beware, lest being carried away with the error of the wicked, you fall from your own steadfastness."},{"v":18,"t":"But grow in the grace and knowledge of our Lord and Savior Jesus Christ. To him be the glory both now and forever. Amen."}],"hr":[{"v":1,"t":"Ljubljeni, pišem evo već drugu poslanicu. U objema opomenom budim vaš zdrav razbor"},{"v":2,"t":"da se sjetite riječi što ih prorekoše sveti proroci i zapovijedi apostola vaših, zapovijedi Gospodinove i Spasiteljeve."},{"v":3,"t":"Znajte ponajprije ovo: u posljednje će se dane pojaviti podrugljivi izrugivači; povoditi će se za svojim požudama"},{"v":4,"t":"i pitati: “Što je s obećanjem njegova Dolaska? Jer i otkad Oci pomriješe, sve ostaje kao što bijaše od početka stvorenja.”"},{"v":5,"t":"Ta oni naumice zaboravljaju da nebesa bijahu odavna i da zemlja na Božju riječ posta iz vode i po vodi."},{"v":6,"t":"Na isti način ondašnji svijet propade vodom potopljen."},{"v":7,"t":"A sadašnja nebesa i zemlja istom su riječju pohranjena za oganj i čuvaju se za Dan suda i propasti bezbožnih ljudi."},{"v":8,"t":"Jedno, ljubljeni, ne smetnite s uma: jedan je dan kod Gospodina kao tisuću godina, a tisuću godina kao jedan dan."},{"v":9,"t":"Ne kasni Gospodin ispuniti obećanje, kako ga neki sporim smatraju, nego je strpljiv prema vama jer neće da tko propadne, nego hoće da svi prispiju k obraćenju."},{"v":10,"t":"Kao tat će doći Dan Gospodnji u koji će nebesa trijeskom uminuti, počela se, užarena, raspasti, a zemlja i djela na njoj razotkriti."},{"v":11,"t":"Kad se sve tako ima raspasti, kako li treba da se svi vi ističete u svetu življenju i pobožnosti"},{"v":12,"t":"iščekujući i pospješujući dolazak Dana Božjega u koji će se nebesa, zapaljena, raspasti i počela, užarena, rastaliti."},{"v":13,"t":"Ta po obećanju njegovu iščekujemo nova nebesa i zemlju novu, gdje pravednost prebiva."},{"v":14,"t":"Zato, ljubljeni, dok to iščekujete, uznastojte da mu budete neokaljani i besprijekorni, u miru."},{"v":15,"t":"A strpljivost Gospodina našega spasenjem smatrajte, kako vam i ljubljeni brat naš Pavao napisa po mudrosti koja mu je dana."},{"v":16,"t":"Tako u svim poslanicama gdje o tome govori. U njima ima ponešto nerazumljivo, što neupućeni i nepostojani iskrivljuju, kao i ostala Pisma - sebi na propast."},{"v":17,"t":"Vi dakle, ljubljeni pošto ste upozoreni, čuvajte se da ne biste, zavedeni bludnjom razularenika, otpali od svoje postojanosti."},{"v":18,"t":"A rastite u milosti i spoznanju Gospodina našega i Spasitelja Isusa Krista! Njemu slava i sada i do u dan vječnosti! Amen!"}]}},"1JN":{"1":{"fa":[{"v":1,"t":"آنچه از ابتدا بود و آنچه شنیده‌ایم و به چشم خود دیده، آنچه بر آن نگریستیم ودستهای ما لمس کرد، درباره کلمه حیات."},{"v":2,"t":"وحیات ظاهر شد و آن را دیده‌ایم و شهادت می‌دهیم و به شما خبر می‌دهیم از حیات جاودانی که نزد پدر بود و برما ظاهر شد."},{"v":3,"t":"ازآنچه دیده و شنیده‌ایم شما را اعلام می‌نماییم تاشما هم با ما شراکت داشته باشید. و اما شراکت مابا پدر و با پسرش عیسی مسیح است."},{"v":4,"t":"و این را به شما می‌نویسم تا خوشی ما کامل گردد."},{"v":5,"t":"و این است پیغامی که از او شنیده‌ایم و به شما اعلام می‌نماییم، که خدا نور است و هیچ ظلمت در وی هرگز نیست."},{"v":6,"t":"اگر گوییم که با وی شراکت داریم، در حالیکه در ظلمت سلوک می‌نماییم، دروغ می‌گوییم و براستی عمل نمی کنیم."},{"v":7,"t":"لکن اگر در نور سلوک می‌نماییم، چنانکه او در نور است، با یکدیگر شراکت داریم و خون پسر او عیسی مسیح ما را از هر گناه پاک می‌سازد."},{"v":8,"t":"اگر گوییم که گناه نداریم خود را گمراه می‌کنیم و راستی در ما نیست."},{"v":9,"t":"اگر به گناهان خود اعتراف کنیم، او امین و عادل است تا گناهان ما را بیامرزد و ما را از هر ناراستی پاک سازد."},{"v":10,"t":"اگر گوییم که گناه نکرده‌ایم، او را دروغگو می شماریم و کلام او در ما نیست."}],"en":[{"v":1,"t":"That which was from the beginning, that which we have heard, that which we have seen with our eyes, that which we saw, and our hands touched, concerning the Word of life"},{"v":2,"t":"(and the life was revealed, and we have seen, and testify, and declare to you the life, the eternal life, which was with the Father, and was revealed to us);"},{"v":3,"t":"that which we have seen and heard we declare to you, that you also may have fellowship with us. Yes, and our fellowship is with the Father and with his Son, Jesus Christ."},{"v":4,"t":"And we write these things to you, that our joy may be fulfilled."},{"v":5,"t":"This is the message which we have heard from him and announce to you, that God is light, and in him is no darkness at all."},{"v":6,"t":"If we say that we have fellowship with him and walk in the darkness, we lie and don’t tell the truth."},{"v":7,"t":"But if we walk in the light as he is in the light, we have fellowship with one another, and the blood of Jesus Christ his Son, cleanses us from all sin."},{"v":8,"t":"If we say that we have no sin, we deceive ourselves, and the truth is not in us."},{"v":9,"t":"If we confess our sins, he is faithful and righteous to forgive us the sins and to cleanse us from all unrighteousness."},{"v":10,"t":"If we say that we haven’t sinned, we make him a liar, and his word is not in us."}],"hr":[{"v":1,"t":"Što bijaše od početka, što smo čuli, što smo vidjeli očima svojim, što razmotrismo i ruke naše opipaše o Riječi, Životu -"},{"v":2,"t":"da, Život se očitova, i vidjeli smo i svjedočimo, i navješćujemo vam Život vječni, koji bijaše kod Oca i očitova se nama -"},{"v":3,"t":"što smo vidjeli i čuli, navješćujemo i vama da i vi imate zajedništvo s nama. A naše je zajedništvo s Ocem i sa Sinom njegovim Isusom Kristom."},{"v":4,"t":"I to vam pišemo da radost naša bude potpuna."},{"v":5,"t":"A ovo je navještaj koji smo čuli od njega i navješćujemo vama: Bog je svjetlost i tame u njemu nema nikakve!"},{"v":6,"t":"Reknemo li da imamo zajedništvo s njim, a u tami hodimo, lažemo i ne činimo istine."},{"v":7,"t":"Ako u svjetlosti hodimo, kao što je on u svjetlosti, imamo zajedništvo jedni s drugima i krv Isusa, Sina njegova, čisti nas od svakoga grijeha."},{"v":8,"t":"Reknemo li da grijeha nemamo, sami sebe varamo i istine nema u nama."},{"v":9,"t":"Ako priznamo grijehe svoje, vjeran je on i pravedan: otpustit će nam grijehe i očistiti nas od svake nepravde."},{"v":10,"t":"Reknemo li da nismo zgriješili, pravimo ga lašcem i riječi njegove nema u nama."}]},"2":{"fa":[{"v":1,"t":"ای فرزندان من، این را به شما می‌نویسم تاگناه نکنید؛ و اگر کسی گناهی کند، شفیعی داریم نزد پدر یعنی عیسی مسیح عادل."},{"v":2,"t":"واوست کفاره بجهت گناهان ما و نه گناهان ما فقطبلکه بجهت تمام جهان نیز."},{"v":3,"t":"و از این می‌دانیم که او را می‌شناسیم، اگر احکام او را نگاه داریم."},{"v":4,"t":"کسی‌که گوید او را می‌شناسم و احکام او رانگاه ندارد، دروغگوست و در وی راستی نیست."},{"v":5,"t":"لکن کسی‌که کلام او را نگاه دارد، فی الواقع محبت خدا در وی کامل شده است و از این می‌دانیم که در وی هستیم."},{"v":6,"t":"هرکه گوید که در وی می‌مانم، به همین طریقی که او سلوک می‌نمود، اونیز باید سلوک کند."},{"v":7,"t":"‌ای حبیبان، حکمی تازه به شما نمی نویسم، بلکه حکمی کهنه که آن را از ابتدا داشتید؛ و حکم کهنه آن کلام است که از ابتدا شنیدید."},{"v":8,"t":"و نیزحکمی تازه به شما می‌نویسم که آن در وی و درشما حق است، زیرا که تاریکی درگذر است و نورحقیقی الان می‌درخشد."},{"v":9,"t":"کسی‌که می‌گوید که در نور است و از برادرخود نفرت دارد، تا حال در تاریکی است."},{"v":10,"t":"وکسی‌که برادر خود را محبت نماید، در نور ساکن است و لغزش در وی نیست."},{"v":11,"t":"اما کسی‌که ازبرادر خود نفرت دارد، در تاریکی است و درتاریکی راه می‌رود و نمی داند کجا می‌رود زیرا که تاریکی چشمانش را کور کرده است."},{"v":12,"t":"‌ای فرزندان، به شما می‌نویسم زیرا که گناهان شما بخاطر اسم او آمرزیده شده است."},{"v":13,"t":"‌ای پدران، به شما می‌نویسم زیرا او را که ازابتدا است می‌شناسید. ای جوانان، به شمامی نویسم از آنجا که بر شریر غالب شده‌اید. ای بچه‌ها به شما نوشتم زیرا که پدر را می‌شناسید."},{"v":14,"t":"‌ای پدران، به شما نوشتم زیرا او را که ازابتداست می‌شناسید. ای جوانان، به شما نوشتم از آن جهت که توانا هستید و کلام خدا در شماساکن است وبر شریر غلبه یافته‌اید."},{"v":15,"t":"دنیا را وآنچه در دنیاست دوست مدارید زیرا اگر کسی دنیا را دوست دارد، محبت پدر در وی نیست."},{"v":16,"t":"زیرا که آنچه در دنیاست، از شهوت جسم وخواهش چشم و غرور زندگانی از پدر نیست بلکه از جهان است."},{"v":17,"t":"و دنیا و شهوات آن در گذراست لکن کسی‌که به اراده خدا عمل می‌کند، تا به ابد باقی می‌ماند."},{"v":18,"t":"‌ای بچه‌ها، این ساعت آخر است و چنانکه شنیده‌اید که دجال می‌آید، الحال هم دجالان بسیار ظاهر شده‌اند و از این می‌دانیم که ساعت آخر است."},{"v":19,"t":"از ما بیرون شدند، لکن از ما نبودند، زیرا اگر از ما می‌بودند با ما می‌ماندند؛ لکن بیرون رفتند تا ظاهر شود که همه ایشان از ما نیستند."},{"v":20,"t":"و اما شما از آن قدوس، مسح را یافته‌اید وهرچیز را می‌دانید."},{"v":21,"t":"ننوشتم به شما از این جهت که راستی را نمی دانید، بلکه از اینرو که آن رامی دانید و اینکه هیچ دروغ از راستی نیست."},{"v":22,"t":"دروغگو کیست جز آنکه مسیح بودن عیسی راانکار کند. آن دجال است که پدر و پسر را انکارمی نماید."},{"v":23,"t":"کسی‌که پسر را انکار کند، پدر را هم ندارد و کسی‌که اعتراف به پسر نماید، پدر را نیزدارد."},{"v":24,"t":"و اما شما آنچه از ابتدا شنیدید در شماثابت بماند، زیرا اگر آنچه از اول شنیدید، در شماثابت بماند، شما نیز در پسر و در پدر ثابت خواهید ماند."},{"v":25,"t":"و این است آن وعده‌ای که او به ما داده است، یعنی حیات جاودانی."},{"v":26,"t":"و این را به شما نوشتم درباره آنانی که شما را گمراه می‌کنند."},{"v":27,"t":"و اما در شما آن مسح که از او یافته‌اید ثابت است و حاجت ندارید که کسی شما را تعلیم دهدبلکه چنانکه خود آن مسح شما را از همه‌چیزتعلیم می‌دهد و حق است و دروغ نیست، پس بطوری که شما را تعلیم داد در او ثابت می‌مانید."},{"v":28,"t":"الان‌ای فرزندان در او ثابت بمانید تا چون ظاهر شود، اعتماد داشته باشیم و در هنگام ظهورش از وی خجل نشویم."},{"v":29,"t":"اگر فهمیده ایدکه او عادل است، پس می‌دانید که هر‌که عدالت رابه‌جا آورد، از وی تولد یافته است."}],"en":[{"v":1,"t":"My little children, I write these things to you so that you may not sin. If anyone sins, we have a Counselor with the Father, Jesus Christ, the righteous."},{"v":2,"t":"And he is the atoning sacrifice for our sins, and not for ours only, but also for the whole world."},{"v":3,"t":"This is how we know that we know him: if we keep his commandments."},{"v":4,"t":"One who says, “I know him,” and doesn’t keep his commandments, is a liar, and the truth isn’t in him."},{"v":5,"t":"But God’s love has most certainly been perfected in whoever keeps his word. This is how we know that we are in him:"},{"v":6,"t":"he who says he remains in him ought himself also to walk just like he walked."},{"v":7,"t":"Brothers, I write no new commandment to you, but an old commandment which you had from the beginning. The old commandment is the word which you heard from the beginning."},{"v":8,"t":"Again, I write a new commandment to you, which is true in him and in you, because the darkness is passing away and the true light already shines."},{"v":9,"t":"He who says he is in the light and hates his brother is in the darkness even until now."},{"v":10,"t":"He who loves his brother remains in the light, and there is no occasion for stumbling in him."},{"v":11,"t":"But he who hates his brother is in the darkness, and walks in the darkness, and doesn’t know where he is going, because the darkness has blinded his eyes."},{"v":12,"t":"I write to you, little children, because your sins are forgiven you for his name’s sake."},{"v":13,"t":"I write to you, fathers, because you know him who is from the beginning. I write to you, young men, because you have overcome the evil one. I write to you, little children, because you know the Father."},{"v":14,"t":"I have written to you, fathers, because you know him who is from the beginning. I have written to you, young men, because you are strong, and the word of God remains in you, and you have overcome the evil one."},{"v":15,"t":"Don’t love the world or the things that are in the world. If anyone loves the world, the Father’s love isn’t in him."},{"v":16,"t":"For all that is in the world—the lust of the flesh, the lust of the eyes, and the pride of life—isn’t the Father’s, but is the world’s."},{"v":17,"t":"The world is passing away with its lusts, but he who does God’s will remains forever."},{"v":18,"t":"Little children, these are the end times, and as you heard that the Antichrist is coming, even now many antichrists have arisen. By this we know that it is the final hour."},{"v":19,"t":"They went out from us, but they didn’t belong to us; for if they had belonged to us, they would have continued with us. But they left, that they might be revealed that none of them belong to us."},{"v":20,"t":"You have an anointing from the Holy One, and you all have knowledge."},{"v":21,"t":"I have not written to you because you don’t know the truth, but because you know it, and because no lie is of the truth."},{"v":22,"t":"Who is the liar but he who denies that Jesus is the Christ? This is the Antichrist, he who denies the Father and the Son."},{"v":23,"t":"Whoever denies the Son doesn’t have the Father. He who confesses the Son has the Father also."},{"v":24,"t":"Therefore, as for you, let that remain in you which you heard from the beginning. If that which you heard from the beginning remains in you, you also will remain in the Son, and in the Father."},{"v":25,"t":"This is the promise which he promised us, the eternal life."},{"v":26,"t":"These things I have written to you concerning those who would lead you astray."},{"v":27,"t":"As for you, the anointing which you received from him remains in you, and you don’t need for anyone to teach you. But as his anointing teaches you concerning all things, and is true, and is no lie, and even as it taught you, you will remain in him."},{"v":28,"t":"Now, little children, remain in him, that when he appears, we may have boldness and not be ashamed before him at his coming."},{"v":29,"t":"If you know that he is righteous, you know that everyone who practices righteousness has been born of him."}],"hr":[{"v":1,"t":"Dječice moja, ovo vam pišem da ne griješite. Ako tko i sagriješi, zagovornika imamo kod Oca - Isusa Krista, Pravednika."},{"v":2,"t":"On je pomirnica za grijeha naše, i ne samo naše, nego i svega svijeta."},{"v":3,"t":"I po ovom znamo da ga poznajemo: ako zapovijedi njegove čuvamo."},{"v":4,"t":"Tko veli: “Poznajem ga”, a zapovijedi njegovih ne čuva, lažac je, u njemu nema istine."},{"v":5,"t":"A tko čuva riječ njegovu, u njemu je zaista savršena ljubav Božja. Po tom znamo da smo u njemu."},{"v":6,"t":"Tko veli da u njemu ostaje, valja mu ići putom kojim je on hodio."},{"v":7,"t":"Ljubljeni, pišem vam ne novu zapovijed, nego staru zapovijed, koju ste imali od početka. Ta stara zapovijed jest riječ koju ste čuli."},{"v":8,"t":"A opet, novu vam zapovijed pišem - obistinjuje se u njemu i vama - jer tama prolazi, svjetlost istinita već svijetli."},{"v":9,"t":"Tko veli da je u svjetlosti, a mrzi brata svojega, u tami je sve do sada."},{"v":10,"t":"Tko ljubi brata svojega, u svjetlosti ostaje i sablazni u njemu nema."},{"v":11,"t":"A tko mrzi brata svojega, u tami je, u tami hodi i ne zna kamo ide jer mu tama zaslijepi oči."},{"v":12,"t":"Pišem vama, dječice, jer su vam grijesi oprošteni po njegovu imenu."},{"v":13,"t":"Pišem vama, oci, jer upoznaste onoga koji je od početka. Pišem vama, mladići, jer ste pobijedili Zloga."},{"v":14,"t":"Napisah vama, djeco, jer upoznaste Oca. Napisah vama, oci, jer upoznaste onoga koji je od početka. Napisah vama, mladići, jer ste jaki i riječ Božja u vama ostaje i pobijedili ste Zloga."},{"v":15,"t":"Ne ljubite svijeta ni što je u svijetu. Ako tko ljubi svijet, nema u njemu ljubavi Očeve."},{"v":16,"t":"Jer što je god svjetovno - požuda tijela, i požuda očiju, i oholost života - nije od Oca, nego od svijeta."},{"v":17,"t":"Svijet prolazi i požuda njegova, a tko čini volju Božju, ostaje dovijeka."},{"v":18,"t":"Djeco, posljednji je čas! I, kako ste čuli, dolazi Antikrist. I sad su se već mnogi antikristi pojavili. Odatle znamo da je posljednji čas."},{"v":19,"t":"Od nas iziđoše, ali ne bijahu od nas. Jer kad bi bili od nas, ostali bi s nama; ali neka se očituje da nisu od nas."},{"v":20,"t":"A vi imate Pomazanje od Svetoga, i znanje svi imate."},{"v":21,"t":"Ne pisah vam zato što ne biste znali istine, nego jer je znate i jer znate da nikakva laž nije od istine."},{"v":22,"t":"Tko je lažac, ako ne onaj koji tvrdi da Isus nije Krist? Antikrist je onaj"},{"v":23,"t":"tko niječe Oca i Sina. Svaki koji niječe Sina, nema ni Oca, a tko priznaje Sina, ima i Oca."},{"v":24,"t":"A vi - što čuste od početka, u vama nek ostane. Ako u vama ostane što čuste od početka, i vi ćete ostati u Sinu i Ocu."},{"v":25,"t":"A ovo je obećanje koje nam on obeća: život vječni."},{"v":26,"t":"Ovo vam napisah o onima koji vas zavode."},{"v":27,"t":"A vi - Pomazanje koje primiste od njega u vama ostaje i ne treba da vas itko poučava. Nego njegovo vas Pomazanje uči o svemu, a istinito je i nije laž, pa kao što vas je ono naučilo, ostanite u Njemu."},{"v":28,"t":"I sada, dječice, ostanite u njemu da budemo puni pouzdanja kad se pojavi te se ne postidimo pred njim o njegovu dolasku."},{"v":29,"t":"Ako znate da je on Pravednik, znate i da je svaki koji čini pravdu od njega rođen."}]},"3":{"fa":[{"v":1,"t":"ملاحظه کنید چه نوع محبت پدر به ما داده است تا فرزندان خدا خوانده شویم؛ وچنین هستیم و از این جهت دنیا ما را نمی شناسدزیرا که او را نشناخت."},{"v":2,"t":"‌ای حبیبان، الان فرزندان خدا هستیم و هنوز ظاهر نشده است آنچه خواهیم بود؛ لکن می‌دانیم که چون او ظاهر شود، مانند او خواهیم بود زیرا او را چنانکه هست خواهیم دید."},{"v":3,"t":"و هرکس که این امید را بر وی دارد، خود را پاک می‌سازد چنانکه او پاک است."},{"v":4,"t":"و هرکه گناه را بعمل می‌آورد، برخلاف شریعت عمل می‌کند زیرا گناه مخالف شریعت است."},{"v":5,"t":"و می‌دانید که او ظاهر شد تا گناهان رابردارد و در وی هیچ گناه نیست."},{"v":6,"t":"هرکه در وی ثابت است گناه نمی کند و هرکه گناه می‌کند او راندیده است و نمی شناسد."},{"v":7,"t":"‌ای فرزندان، کسی شما را گمراه نکند؛ کسی‌که عدالت را به‌جا می‌آورد، عادل است چنانکه اوعادل است."},{"v":8,"t":"و کسی‌که گناه می‌کند از ابلیس است زیرا که ابلیس از ابتدا گناهکار بوده است. واز این جهت پسر خدا ظاهر شد تا اعمال ابلیس راباطل سازد."},{"v":9,"t":"هر‌که از خدا مولود شده است، گناه نمی کند زیرا تخم او در وی می‌ماند و اونمی تواند گناهکار بوده باشد زیرا که از خدا تولدیافته است."},{"v":10,"t":"فرزندان خدا و فرزندان ابلیس ازاین ظاهر می‌گردند. هر‌که عدالت را به‌جانمی آورد از خدا نیست و همچنین هر‌که برادرخود را محبت نمی نماید."},{"v":11,"t":"زیرا همین است آن پیغامی که از اول شنیدید که یکدیگر را محبت نماییم."},{"v":12,"t":"نه مثل قائن که از آن شریر بود و برادر خود را کشت؛ و ازچه سبب او را کشت؟ از این سبب که اعمال خودش قبیح بود و اعمال برادرش نیکو."},{"v":13,"t":"‌ای برادران من، تعجب مکنید اگر دنیا از شما نفرت گیرد."},{"v":14,"t":"ما می‌دانیم که از موت گذشته، داخل حیات گشته‌ایم از اینکه برادران را محبت می نماییم. هرکه برادر خود را محبت نمی نمایددر موت ساکن است."},{"v":15,"t":"هر‌که از برادر خود نفرت نماید، قاتل است و می‌دانید که هیچ قاتل حیات جاودانی در خود ثابت ندارد."},{"v":16,"t":"از این امر محبت را دانسته‌ایم که او جان خود را در راه ما نهاد و ما باید جان خود را در راه برادران بنهیم."},{"v":17,"t":"لکن کسی‌که معیشت دنیوی دارد و برادر خود را محتاج بیند و رحمت خود رااز او باز‌دارد، چگونه محبت خدا در او ساکن است؟"},{"v":18,"t":"‌ای فرزندان، محبت را به‌جا آریم نه درکلام و زبان بلکه در عمل و راستی."},{"v":19,"t":"و از این خواهیم دانست که از حق هستیم و دلهای خود رادر حضور او مطمئن خواهیم ساخت،"},{"v":20,"t":"یعنی درهرچه دل ما، ما را مذمت می‌کند، زیرا خدا از دل ما بزرگتر است و هرچیز را می‌داند."},{"v":21,"t":"‌ای حبیبان، هرگاه دل ما ما را مذمت نکند، در حضور خدا اعتماد داریم."},{"v":22,"t":"و هرچه سوآل کنیم، از او می‌پاییم، از آنجهت که احکام او رانگاه می‌داریم و به آنچه پسندیده اوست، عمل می‌نماییم. و این است حکم او که به اسم پسر اوعیسی مسیح ایمان آوریم و یکدیگر را محبت نماییم، چنانکه به ما امر فرمود."},{"v":23,"t":"و هرکه احکام او را نگاه دارد، در او ساکن است و او در وی؛ و ازاین می‌شناسیم که در ما ساکن است، یعنی از آن روح که به ما داده است."}],"en":[{"v":1,"t":"See how great a love the Father has given to us, that we should be called children of God! For this cause the world doesn’t know us, because it didn’t know him."},{"v":2,"t":"Beloved, now we are children of God. It is not yet revealed what we will be; but we know that when he is revealed, we will be like him, for we will see him just as he is."},{"v":3,"t":"Everyone who has this hope set on him purifies himself, even as he is pure."},{"v":4,"t":"Everyone who sins also commits lawlessness. Sin is lawlessness."},{"v":5,"t":"You know that he was revealed to take away our sins, and no sin is in him."},{"v":6,"t":"Whoever remains in him doesn’t sin. Whoever sins hasn’t seen him and doesn’t know him."},{"v":7,"t":"Little children, let no one lead you astray. He who does righteousness is righteous, even as he is righteous."},{"v":8,"t":"He who sins is of the devil, for the devil has been sinning from the beginning. To this end the Son of God was revealed: that he might destroy the works of the devil."},{"v":9,"t":"Whoever is born of God doesn’t commit sin, because his seed remains in him, and he can’t sin, because he is born of God."},{"v":10,"t":"In this the children of God are revealed, and the children of the devil. Whoever doesn’t do righteousness is not of God, neither is he who doesn’t love his brother."},{"v":11,"t":"For this is the message which you heard from the beginning, that we should love one another—"},{"v":12,"t":"unlike Cain, who was of the evil one and killed his brother. Why did he kill him? Because his deeds were evil, and his brother’s righteous."},{"v":13,"t":"Don’t be surprised, my brothers, if the world hates you."},{"v":14,"t":"We know that we have passed out of death into life, because we love the brothers. He who doesn’t love his brother remains in death."},{"v":15,"t":"Whoever hates his brother is a murderer, and you know that no murderer has eternal life remaining in him."},{"v":16,"t":"By this we know love, because he laid down his life for us. And we ought to lay down our lives for the brothers."},{"v":17,"t":"But whoever has the world’s goods and sees his brother in need, then closes his heart of compassion against him, how does God’s love remain in him?"},{"v":18,"t":"My little children, let’s not love in word only, or with the tongue only, but in deed and truth."},{"v":19,"t":"And by this we know that we are of the truth and persuade our hearts before him,"},{"v":20,"t":"because if our heart condemns us, God is greater than our heart, and knows all things."},{"v":21,"t":"Beloved, if our hearts don’t condemn us, we have boldness toward God;"},{"v":22,"t":"so whatever we ask, we receive from him, because we keep his commandments and do the things that are pleasing in his sight."},{"v":23,"t":"This is his commandment, that we should believe in the name of his Son, Jesus Christ, and love one another, even as he commanded."},{"v":24,"t":"He who keeps his commandments remains in him, and he in him. By this we know that he remains in us, by the Spirit which he gave us."}],"hr":[{"v":1,"t":"Gledajte koliku nam je ljubav darovao Otac: djeca se Božja zovemo, i jesmo. A svijet nas ne poznaje zato što ne poznaje njega."},{"v":2,"t":"Ljubljeni, sad smo djeca Božja i još se ne očitova što ćemo biti. Znamo: kad se očituje, bit ćemo njemu slični, jer vidjet ćemo ga kao što jest."},{"v":3,"t":"I tko god ima tu nadu u njemu, čisti se kao što je on čist."},{"v":4,"t":"Tko god čini grijeh, čini i bezakonje; ta grijeh je bezakonje."},{"v":5,"t":"I znate: on se pojavi da odnese grijehe i grijeha nema u njemu."},{"v":6,"t":"Tko god u njemu ostaje, ne griješi. Tko god griješi, nije ga vidio nit upoznao."},{"v":7,"t":"Dječice, nitko neka vas ne zavede! Tko čini pravdu, pravedan je kao što je On pravedan."},{"v":8,"t":"Tko čini grijeh, od đavla je jer đavao griješi od početka. Zato se pojavi Sin Božji: da razori djela đavolska."},{"v":9,"t":"Tko god je rođen od Boga, ne čini grijeha jer njegovo sjeme ostaje u njemu; ne može griješiti jer je rođen od Boga."},{"v":10,"t":"Po ovom se raspoznaju djeca Božja i djeca đavolska: tko god ne čini pravde i tko ne ljubi brata, nije od Boga."},{"v":11,"t":"Jer ovo je navještaj koji čuste od početka: da ljubimo jedni druge."},{"v":12,"t":"Ne kao Kajin, koji bijaše od Zloga i ubi brata svog. A zašto ga ubi? Jer mu djela bijahu zla, a bratova pravedna."},{"v":13,"t":"Ne čudite se, braćo ako vas svijet mrzi."},{"v":14,"t":"Mi znamo da smo iz smrti prešli u život jer ljubimo braću; tko ne ljubi, ostaje u smrti."},{"v":15,"t":"Tko god mrzi brata svoga, ubojica je. A znate da nijedan ubojica nema u sebi trajnoga, vječnoga života."},{"v":16,"t":"Po ovom smo upoznali Ljubav: on je za nas položio život svoj. I mi smo dužni živote položiti za braću."},{"v":17,"t":"Tko ima dobra ovoga svijeta i vidi brata svoga u potrebi pa zatvori pred njim srce - kako ljubav Božja ostaje u njemu?"},{"v":18,"t":"Dječice, ne ljubimo riječju i jezikom, već djelom i istinom."},{"v":19,"t":"Po tom ćemo znati da smo od istine. I umirit ćemo pred njim srce svoje"},{"v":20,"t":"ako nas ono bilo u čem osuđuje. Jer Bog je veći od našega srca i znade sve."},{"v":21,"t":"Ljubljeni, ako nas srce ne osuđuje, možemo zaufano k Bogu."},{"v":22,"t":"I što god ištemo, primamo od njega jer zapovijedi njegove čuvamo i činimo što je njemu drago."},{"v":23,"t":"I ovo je zapovijed njegova: da vjerujemo u ime Sina njegova Isusa Krista i da ljubimo jedni druge kao što nam je dao zapovijed."},{"v":24,"t":"I tko čuva zapovijedi njegove, u njemu ostaje, i On u njemu. I po ovom znamo da on ostaje u nama: po Duhu kojeg nam je dao."}]},"4":{"fa":[{"v":1,"t":"ای حبیبان، هر روح را قبول مکنید بلکه روح‌ها را بیازمایید که از خدا هستند یا نه. زیرا که انبیای کذبه بسیار به جهان بیرون رفته‌اند."},{"v":2,"t":"به این، روح خدا را می‌شناسیم: هر روحی که به عیسی مسیح مجسم شده اقرار نماید از خداست،"},{"v":3,"t":"و هر روحی که عیسی مسیح مجسم شده راانکار کند، از خدا نیست. و این است روح دجال که شنیده‌اید که او می‌آید و الان هم در جهان است."},{"v":4,"t":"‌ای فرزندان، شما از خدا هستید و بر ایشان غلبه یافته‌اید زیرا او که در شماست، بزرگتر است از آنکه در جهان است."},{"v":5,"t":"ایشان از دنیا هستند ازاین جهت سخنان دنیوی می‌گویند و دنیا ایشان رامی شنود."},{"v":6,"t":"ما از خدا هستیم و هرکه خدا رامی شناسد ما را می‌شنود و آنکه از خدا نیست مارا نمی شنود. روح حق و روح ضلالت را از این تمییز می‌دهیم."},{"v":7,"t":"‌ای حبیبان، یکدیگر را محبت بنماییم زیراکه محبت از خداست و هرکه محبت می‌نماید ازخدا مولود شده است و خدا را می‌شناسد،"},{"v":8,"t":"وکسی‌که محبت نمی نماید، خدا را نمی شناسدزیرا خدا محبت است."},{"v":9,"t":"و محبت خدا به ما ظاهرشده است به اینکه خدا پسر یگانه خود را به جهان فرستاده است تا به وی زیست نماییم."},{"v":10,"t":"ومحبت در همین است، نه آنکه ما خدا را محبت نمودیم، بلکه اینکه او ما را محبت نمود و پسرخود را فرستاد تاکفاره گناهان ما شود."},{"v":11,"t":"‌ای حبیبان، اگر خدا با ما چنین محبت نمود، ما نیزمی باید یکدیگر را محبت نماییم."},{"v":12,"t":"کسی هرگزخدا را ندید؛ اگر یکدیگر را محبت نماییم، خدادر ما ساکن است و محبت او در ما کامل شده است."},{"v":13,"t":"از این می‌دانیم که در وی ساکنیم و او در مازیرا که از روح خود به ما داده است."},{"v":14,"t":"و مادیده‌ایم و شهادت می‌دهیم که پدر پسر را فرستادتا نجات‌دهنده جهان بشود."},{"v":15,"t":"هرکه اقرار می‌کندکه عیسی پسر خداست، خدا در وی ساکن است واو در خدا."},{"v":16,"t":"و ما دانسته و باور کرده‌ایم آن محبتی را که خدا با ما نموده است. خدا محبت است و هرکه در محبت ساکن است در خدا ساکن است و خدا در وی."},{"v":17,"t":"محبت در همین با ما کامل شده است تا درروز جزا ما را دلاوری باشد، زیرا چنانکه اوهست، ما نیز در این جهان همچنین هستیم."},{"v":18,"t":"درمحبت خوف نیست بلکه محبت کامل خوف رابیرون می‌اندازد؛ زیرا خوف عذاب دارد و کسی‌که خوف دارد، در محبت کامل نشده است."},{"v":19,"t":"مااو را محبت می‌نماییم زیرا که او اول ما را محبت نمود."},{"v":20,"t":"اگر کسی گوید که خدا را محبت می‌نمایم و از برادر خود نفرت کند، دروغگوست، زیرا کسی‌که برادری را که دیده است محبت ننماید، چگونه ممکن است خدایی را که ندیده است محبت نماید؟"},{"v":21,"t":"و این حکم رااز وی یافته‌ایم که هرکه خدا را محبت می‌نماید، برادر خود را نیز محبت بنماید."}],"en":[{"v":1,"t":"Beloved, don’t believe every spirit, but test the spirits, whether they are of God, because many false prophets have gone out into the world."},{"v":2,"t":"By this you know the Spirit of God: every spirit who confesses that Jesus Christ has come in the flesh is of God,"},{"v":3,"t":"and every spirit who doesn’t confess that Jesus Christ has come in the flesh is not of God; and this is the spirit of the Antichrist, of whom you have heard that it comes. Now it is in the world already."},{"v":4,"t":"You are of God, little children, and have overcome them, because greater is he who is in you than he who is in the world."},{"v":5,"t":"They are of the world. Therefore they speak of the world, and the world hears them."},{"v":6,"t":"We are of God. He who knows God listens to us. He who is not of God doesn’t listen to us. By this we know the spirit of truth, and the spirit of error."},{"v":7,"t":"Beloved, let’s love one another, for love is of God; and everyone who loves has been born of God and knows God."},{"v":8,"t":"He who doesn’t love doesn’t know God, for God is love."},{"v":9,"t":"By this God’s love was revealed in us, that God has sent his only born Son into the world that we might live through him."},{"v":10,"t":"In this is love, not that we loved God, but that he loved us, and sent his Son as the atoning sacrifice for our sins."},{"v":11,"t":"Beloved, if God loved us in this way, we also ought to love one another."},{"v":12,"t":"No one has seen God at any time. If we love one another, God remains in us, and his love has been perfected in us."},{"v":13,"t":"By this we know that we remain in him and he in us, because he has given us of his Spirit."},{"v":14,"t":"We have seen and testify that the Father has sent the Son as the Savior of the world."},{"v":15,"t":"Whoever confesses that Jesus is the Son of God, God remains in him, and he in God."},{"v":16,"t":"We know and have believed the love which God has for us. God is love, and he who remains in love remains in God, and God remains in him."},{"v":17,"t":"In this, love has been made perfect among us, that we may have boldness in the day of judgment, because as he is, even so we are in this world."},{"v":18,"t":"There is no fear in love; but perfect love casts out fear, because fear has punishment. He who fears is not made perfect in love."},{"v":19,"t":"We love him, because he first loved us."},{"v":20,"t":"If a man says, “I love God,” and hates his brother, he is a liar; for he who doesn’t love his brother whom he has seen, how can he love God whom he has not seen?"},{"v":21,"t":"This commandment we have from him, that he who loves God should also love his brother."}],"hr":[{"v":1,"t":"Ljubljeni, ne vjerujte svakom duhu, nego provjeravajte duhove jesu li od Boga, jer su mnogi lažni proroci izišli u svijet."},{"v":2,"t":"Po ovom prepoznajete Duha Božjega: svaki duh koji ispovijeda da je Isus Krist došao u tijelu, od Boga je."},{"v":3,"t":"A nijedan duh koji ne ispovijeda takva Isusa, nije od Boga: on je Antikristov, a za nj ste čuli da dolazi i sad je već na svijetu."},{"v":4,"t":"Vi ste, dječice, od Boga i pobijedili ste ih jer je moćniji Onaj koji je u vama nego onaj koji je u svijetu."},{"v":5,"t":"Oni su od svijeta, zato iz svijeta govore i svijet ih sluša."},{"v":6,"t":"Mi smo od Boga. Tko poznaje Boga, nas sluša, a tko nije od Boga, ne sluša nas. Po tom prepoznajemo Duha istine i duha zablude."},{"v":7,"t":"Ljubljeni, ljubimo jedni druge jer ljubav je od Boga; i svaki koji ljubi, od Boga je rođen i poznaje Boga."},{"v":8,"t":"Tko ne ljubi, ne upozna Boga jer Bog je ljubav."},{"v":9,"t":"U ovom se očitova ljubav Božja u nama: Bog Sina svoga jedinorođenoga posla u svijet da živimo po njemu."},{"v":10,"t":"U ovom je ljubav: ne da smo mi ljubili Boga, nego - on je ljubio nas i poslao Sina svoga kao pomirnicu za grijehe naše."},{"v":11,"t":"Ljubljeni, ako je Bog tako ljubio nas, i mi smo dužni ljubiti jedni druge."},{"v":12,"t":"Boga nitko nikada ne vidje. Ako ljubimo jedni druge, Bog ostaje u nama, i ljubav je njegova u nama savršena."},{"v":13,"t":"Po ovom znamo da ostajemo u njemu i on u nama: od Duha nam je svoga dao."},{"v":14,"t":"I mi smo vidjeli i svjedočimo da je Otac poslao Sina kao Spasitelja svijeta."},{"v":15,"t":"Tko ispovijeda da je Isus Sin Božji, Bog ostaje u njemu, i on u Bogu."},{"v":16,"t":"I mi smo upoznali ljubav koju Bog ima prema nama i povjerovali joj. Bog je ljubav i tko ostaje u ljubavi, u Bogu ostaje, i Bog u njemu."},{"v":17,"t":"U ovom je savršenstvo naše uzajamne ljubavi: imamo pouzdanje na Sudnji dan jer kakav je on, takvi smo i mi u ovom svijetu."},{"v":18,"t":"Straha u ljubavi nema, nego savršena ljubav izgoni strah; jer strah je muka i tko se boji, nije savršen u ljubavi."},{"v":19,"t":"Mi ljubimo jer on nas prije uzljubi."},{"v":20,"t":"Rekne li tko: “Ljubim Boga”, a mrzi brata svog, lažac je. Jer tko ne ljubi svoga brata kojega vidi, Boga kojega ne vidi ne može ljubiti."},{"v":21,"t":"I ovu zapovijed imamo od njega: Tko ljubi Boga, da ljubi i brata svoga."}]},"5":{"fa":[{"v":1,"t":"هرکه ایمان دارد که عیسی، مسیح است، ازخدا مولود شده است؛ و هرکه والد رامحبت می‌نماید، مولود او را نیز محبت می‌نماید."},{"v":2,"t":"از این می‌دانیم که فرزندان خدا را محبت می نماییم، چون خدا را محبت می‌نماییم واحکام او را به‌جا می‌آوریم."},{"v":3,"t":"زیرا همین است محبت خدا که احکام او را نگاه داریم و احکام اوگران نیست."},{"v":4,"t":"زیرا آنچه از خدا مولود شده است، بر دنیا غلبه می‌یابد؛ و غلبه‌ای که دنیا را مغلوب ساخته است، ایمان ماست."},{"v":5,"t":"کیست آنکه بر دنیاغلبه یابد؟ جز آنکه ایمان دارد که عیسی پسرخداست."},{"v":6,"t":"همین است او که به آب و خون آمد یعنی عیسی مسیح. نه به آب فقط بلکه به آب و خون. وروح است آنکه شهادت می‌دهد، زیرا که روح حق است."},{"v":7,"t":"زیرا سه هستند که شهادت می‌دهند،"},{"v":8,"t":"یعنی روح و آب و خون؛ و این سه یک هستند."},{"v":9,"t":"اگر شهادت انسان را قبول کنیم، شهادت خدابزرگتر است؛ زیرا این است شهادت خدا که درباره پسر خود شهادت داده است."},{"v":10,"t":"آنکه به پسر خدا ایمان آورد، در خود شهادت دارد وآنکه به خدا ایمان نیاورد، او را دروغگو شمرده است، زیرا به شهادتی که خدا درباره پسر خودداده است، ایمان نیاورده است."},{"v":11,"t":"و آن شهادت این است که خدا حیات جاودانی به ما داده است واین حیات، در پسر اوست."},{"v":12,"t":"آنکه پسر را داردحیات را دارد و آنکه پسر خدا را ندارد، حیات رانیافته است."},{"v":13,"t":"این را نوشتم به شما که به اسم خدا ایمان آورده‌اید تا بدانید که حیات جاودانی دارید و تا به اسم پسر خدا ایمان بیاورید."},{"v":14,"t":"و این است آن دلیری که نزد وی داریم که هرچه برحسب اراده او سوال نماییم، ما را می‌شنود."},{"v":15,"t":"و اگر دانیم که هرچه سوال کنیم ما را می‌شنود، پس می‌دانیم که آنچه از او درخواست کنیم می‌یابیم."},{"v":16,"t":"اگر کسی برادر خود را بیند که گناهی را که منتهی به موت نباشد می‌کند، دعا بکند و او را حیات خواهدبخشید، به هرکه گناهی منتهی به موت نکرده باشد. گناهی منتهی به موت هست؛ بجهت آن نمی گویم که دعا باید کرد."},{"v":17,"t":"هر ناراستی گناه است، ولی گناهی هست که منتهی به موت نیست."},{"v":18,"t":"و می‌دانیم که هرکه از خدا مولود شده است، گناه نمی کند بلکه کسی‌که از خدا تولد یافت خودرا نگاه می‌دارد و آن شریر او را لمس نمی کند."},{"v":19,"t":"و می‌دانیم که از خدا هستیم و تمام دنیا درشریر خوابیده است."},{"v":20,"t":"اما آگاه هستیم که پسرخدا آمده است و به ما بصیرت داده است تا حق رابشناسیم و در حق یعنی در پسر او عیسی مسیح هستیم. اوست خدای حق و حیات جاودانی."},{"v":21,"t":"‌ای فرزندان، خود را از بتها نگاه دارید. آمین."}],"en":[{"v":1,"t":"Whoever believes that Jesus is the Christ has been born of God. Whoever loves the Father also loves the child who is born of him."},{"v":2,"t":"By this we know that we love the children of God, when we love God and keep his commandments."},{"v":3,"t":"For this is loving God, that we keep his commandments. His commandments are not grievous."},{"v":4,"t":"For whatever is born of God overcomes the world. This is the victory that has overcome the world: your faith."},{"v":5,"t":"Who is he who overcomes the world, but he who believes that Jesus is the Son of God?"},{"v":6,"t":"This is he who came by water and blood, Jesus Christ; not with the water only, but with the water and the blood. It is the Spirit who testifies, because the Spirit is the truth."},{"v":7,"t":"For there are three who testify:"},{"v":8,"t":"the Spirit, the water, and the blood; and the three agree as one."},{"v":9,"t":"If we receive the witness of men, the witness of God is greater; for this is God’s testimony which he has testified concerning his Son."},{"v":10,"t":"He who believes in the Son of God has the testimony in himself. He who doesn’t believe God has made him a liar, because he has not believed in the testimony that God has given concerning his Son."},{"v":11,"t":"The testimony is this: that God gave to us eternal life, and this life is in his Son."},{"v":12,"t":"He who has the Son has the life. He who doesn’t have God’s Son doesn’t have the life."},{"v":13,"t":"These things I have written to you who believe in the name of the Son of God, that you may know that you have eternal life, and that you may continue to believe in the name of the Son of God."},{"v":14,"t":"This is the boldness which we have toward him, that if we ask anything according to his will, he listens to us."},{"v":15,"t":"And if we know that he listens to us, whatever we ask, we know that we have the petitions which we have asked of him."},{"v":16,"t":"If anyone sees his brother sinning a sin not leading to death, he shall ask, and God will give him life for those who sin not leading to death. There is sin leading to death. I don’t say that he should make a request concerning this."},{"v":17,"t":"All unrighteousness is sin, and there is sin not leading to death."},{"v":18,"t":"We know that whoever is born of God doesn’t sin, but he who was born of God keeps himself, and the evil one doesn’t touch him."},{"v":19,"t":"We know that we are of God, and the whole world lies in the power of the evil one."},{"v":20,"t":"We know that the Son of God has come and has given us an understanding, that we know him who is true; and we are in him who is true, in his Son Jesus Christ. This is the true God and eternal life."},{"v":21,"t":"Little children, keep yourselves from idols."}],"hr":[{"v":1,"t":"Tko god vjeruje: “Isus je Krist”, od Boga je rođen. I tko god ljubi roditelja, ljubi i rođenoga."},{"v":2,"t":"Po ovom znamo da ljubimo djecu Božju: kad Boga ljubimo i zapovijedi njegove vršimo."},{"v":3,"t":"Jer ljubav je Božja ovo: zapovijedi njegove čuvati. A zapovijedi njegove nisu teške."},{"v":4,"t":"Jer sve što je od Boga rođeno, pobjeđuje svijet. I ovo je pobjeda što pobijedi svijet: vjera naša."},{"v":5,"t":"Ta tko to pobjeđuje svijet ako ne onaj tko vjeruje da je Isus Sin Božji?"},{"v":6,"t":"On, Isus Krist, dođe kroz vodu i krv. Ne samo u vodi nego - u vodi i krvi. I Duh je koji svjedoči jer Duh je istina."},{"v":7,"t":"Jer troje je što svjedoči:"},{"v":8,"t":"Duh, voda i krv; i to je troje jedno."},{"v":9,"t":"Ako primamo svjedočanstvo ljudi, svjedočanstvo je Božje veće. Jer ovo je svjedočanstvo Božje, kojim je svjedočio za Sina svoga:"},{"v":10,"t":"Tko vjeruje u Sina Božjega, ima to svjedočanstvo Božje u sebi. Tko ne vjeruje Bogu, učinio ga je lašcem jer nije vjerovao u svjedočanstvo kojim je svjedočio Bog za Sina svoga."},{"v":11,"t":"I ovo je svjedočanstvo: Bog nam je dao život vječni; i taj je život u Sinu njegovu."},{"v":12,"t":"Tko ima Sina, ima život; tko nema Sina Božjega, nema života."},{"v":13,"t":"To napisah vama koji vjerujete u ime Sina Božjega da znate da imate život vječni."},{"v":14,"t":"I ovo je pouzdanje koje imamo u njega: ako što ištemo po volji njegovoj, uslišava nas."},{"v":15,"t":"I znamo li da nas uslišava u svemu što ištemo, znamo da već imamo što smo od njega iskali."},{"v":16,"t":"Vidi li tko brata svojega gdje čini grijeh koji nije na smrt, neka ište i dat će mu život - onima koji čine grijeh što nije na smrt. Ima grijeh što je na smrt; za nj ne velim da moli."},{"v":17,"t":"Svaka je nepravda grijeh. A postoji grijeh koji nije na smrt."},{"v":18,"t":"Znamo: tko god je rođen od Boga, ne griješi; nego Rođeni od Boga čuva ga i Zli ga se ne dotiče."},{"v":19,"t":"Znamo: od Boga smo, a sav je svijet pod Zlim."},{"v":20,"t":"Znamo: Sin je Božji došao i dao nam razum da poznamo Istinitoga. I mi smo u Istinitom, u Sinu njegovu, Isusu Kristu. On je Bog istiniti i Život vječni."},{"v":21,"t":"Dječice, klonite se idola!"}]}},"2JN":{"1":{"fa":[{"v":1,"t":"من که پیرم، به خاتون برگزیده و فرزندانش که ایشان را درراستی محبت می‌نمایم و نه من فقط بلکه همه کسانی که راستی را می‌دانند،"},{"v":2,"t":"بخاطر آن راستی که در ما ساکن است و با ما تا به ابد خواهدبود."},{"v":3,"t":"فیض و رحمت و سلامتی از جانب خدای پدر و عیسی مسیح خداوند و پسر پدر در راستی و محبت با ما خواهد بود."},{"v":4,"t":"بسیار مسرور شدم چونکه بعضی از فرزندان تو را یافتم که در راستی رفتار می‌کنند، چنانکه ازپدر حکم یافتیم."},{"v":5,"t":"و الان‌ای خاتون از تو التماس دارم نه آنکه حکمی تازه به تو بنویسم، بلکه همان را که از ابتداء داشتیم که یکدیگر را محبت بنماییم."},{"v":6,"t":"و این است محبت که موافق احکام اوسلوک بنماییم و حکم همان است که از اول شنیدید تا در آن سلوک نماییم."},{"v":7,"t":"زیرا گمراه کنندگان بسیار به‌دنیا بیرون شدندکه عیسی مسیح ظاهر شده در جسم را اقرارنمی کنند. آن است گمراه‌کننده و دجال."},{"v":8,"t":"خود رانگاه بدارید مبادا آنچه را که عمل کردیم برباددهید بلکه تا اجرت کامل بیابید."},{"v":9,"t":"هرکه پیشوایی می‌کند و در تعلیم مسیح ثابت نیست، خدا رانیافته است. اما آنکه در تعلیم مسیح ثابت ماند، اوهم پدر و پسر را دارد."},{"v":10,"t":"اگر کسی به نزد شما آیدو این تعلیم را نیاورد، او را به خانه خود مپذیرید واو را تحیت مگویید."},{"v":11,"t":"زیرا هرکه او را تحیت گوید، در کارهای قبیحش شریک گردد."},{"v":12,"t":"چیزهای بسیار دارم که به شما بنویسم، لکن نخواستم که به کاغذ و مرکب بنویسم، بلکه امیدوارم که به نزد شما بیایم و زبانی گفتگو نمایم تا خوشی ما کامل شود."},{"v":13,"t":"فرزندان خواهر برگزیده تو، به تو سلام می‌رسانند. آمین."}],"en":[{"v":1,"t":"The elder, to the chosen lady and her children, whom I love in truth, and not I only, but also all those who know the truth,"},{"v":2,"t":"for the truth’s sake, which remains in us, and it will be with us forever:"},{"v":3,"t":"Grace, mercy, and peace will be with us, from God the Father and from the Lord Jesus Christ, the Son of the Father, in truth and love."},{"v":4,"t":"I rejoice greatly that I have found some of your children walking in truth, even as we have been commanded by the Father."},{"v":5,"t":"Now I beg you, dear lady, not as though I wrote to you a new commandment, but that which we had from the beginning, that we love one another."},{"v":6,"t":"This is love, that we should walk according to his commandments. This is the commandment, even as you heard from the beginning, that you should walk in it."},{"v":7,"t":"For many deceivers have gone out into the world, those who don’t confess that Jesus Christ came in the flesh. This is the deceiver and the Antichrist."},{"v":8,"t":"Watch yourselves, that we don’t lose the things which we have accomplished, but that we receive a full reward."},{"v":9,"t":"Whoever transgresses and doesn’t remain in the teaching of Christ doesn’t have God. He who remains in the teaching has both the Father and the Son."},{"v":10,"t":"If anyone comes to you and doesn’t bring this teaching, don’t receive him into your house, and don’t welcome him,"},{"v":11,"t":"for he who welcomes him participates in his evil deeds."},{"v":12,"t":"Having many things to write to you, I don’t want to do so with paper and ink, but I hope to come to you and to speak face to face, that our joy may be made full."},{"v":13,"t":"The children of your chosen sister greet you. Amen."}],"hr":[{"v":1,"t":"Starješina izabranoj Gospođi i djeci njezinoj koju ja ljubim u Istini - a ne samo ja nego i svi koji upoznaše Istinu -"},{"v":2,"t":"radi Istine koja ostaje u nama i bit će s nama dovijeka."},{"v":3,"t":"Bila s nama milost, milosrđe i mir od Boga Oca i od Sina Očeva Isusa Krista u istini i ljubavi!"},{"v":4,"t":"Obradovah se veoma što sam među tvojom djecom našao takve koji hode u istini, kao što primismo zapovijed od Oca."},{"v":5,"t":"I sada te molim, Gospođo, ne kao da ti novu zapovijed pišem, nego onu koju smo imali od početka: da ljubimo jedni druge."},{"v":6,"t":"A ovo je ta ljubav: da živimo po zapovijedima njegovim. To je zapovijed, kao što čuste od početka, da u njoj živite."},{"v":7,"t":"Jer iziđoše na svijet mnogi zavodnici koji ne ispovijedaju Isusa Krista koji dolazi u tijelu. To je zavodnik i Antikrist."},{"v":8,"t":"Čuvajte se da ne izgubite što ste stekli, nego da primite potpunu plaću."},{"v":9,"t":"Tko god pretjera i ne ostane u nauku Kristovu, nema Boga. Tko ostaje u nauku, ima i Oca i Sina."},{"v":10,"t":"Ako tko dolazi k vama i ne donosi tog nauka, ne primajte ga u kuću i ne pozdravljajte ga."},{"v":11,"t":"Jer tko ga pozdravlja, sudjeluje u njegovim zlim djelima."},{"v":12,"t":"Mnogo bih vam imao pisati, ali ne htjedoh na papiru i crnilom, nego se nadam da ću doći k vama i iz usta u usta govoriti da radost vaša bude potpuna."},{"v":13,"t":"Pozdravljaju te djeca tvoje izabrane sestre."}]}},"3JN":{"1":{"fa":[{"v":1,"t":"من که پیرم، به غایس حبیب که او را در راستی محبت می‌نمایم."},{"v":2,"t":"‌ای حبیب، دعا می‌کنم که در هر وجه کامیاب و تندرست بوده باشی، چنانکه جان توکامیاب است."},{"v":3,"t":"زیرا که بسیار شاد شدم چون برادران آمدند و بر راستی تو شهادت دادند، چنانکه تو در راستی سلوک می‌نمایی."},{"v":4,"t":"مرا بیش از این شادی نیست که بشنوم که فرزندانم درراستی سلوک می‌نمایند."},{"v":5,"t":"‌ای حبیب، آنچه می‌کنی به برادران خصوص به غریبان، به امانت می‌کنی،"},{"v":6,"t":"که در حضور کلیسا بر محبت توشهادت دادند و هرگاه ایشان را بطور شایسته خدابدرقه کنی، نیکویی می‌نمایی زیرا که بجهت اسم او بیرون رفتند و از امتها چیزی نمی گیرند."},{"v":7,"t":"پس بر ما واجب است که چنین اشخاص را بپذیریم تاشریک راستی بشویم."},{"v":8,"t":"به کلیسا چیزی نوشتم لکن دیوترفیس که سرداری بر ایشان را دوست می‌دارد ما را قبول نمی کند."},{"v":9,"t":"لهذا اگر آیم کارهایی را که او می‌کندبه یاد خواهم آورد زیرا به سخنان ناشایسته برما یاوه‌گویی می‌کند و به این قانع نشده، برادران را خود نمی پذیرد و کسانی را نیز که می‌خواهند، مانع ایشان می‌شود و از کلیسا بیرون می‌کند."},{"v":10,"t":"‌ای حبیب به بدی اقتدا منما بلکه به نیکویی زیرا نیکو‌کردار از خداست و بدکردار خدا راندیده است."},{"v":11,"t":"همه مردم و خود راستی نیز بردیمتریوس شهادت می‌دهند و ما هم شهادت می‌دهیم و آگاهید که شهادت ما راست است."},{"v":12,"t":"مرا چیزهای بسیار بود که به تو بنویسم، لکن نمی خواهم به مرکب و قلم به تو بنویسم."},{"v":13,"t":"لکن امیدوارم که به زودی تو را خواهم دید وزبانی گفتگو کنیم."},{"v":14,"t":"سلام بر تو باد. دوستان به تو سلام می‌رسانند. سلام مرا به دوستان نام به نام برسان."}],"en":[{"v":1,"t":"The elder to Gaius the beloved, whom I love in truth."},{"v":2,"t":"Beloved, I pray that you may prosper in all things and be healthy, even as your soul prospers."},{"v":3,"t":"For I rejoiced greatly when brothers came and testified about your truth, even as you walk in truth."},{"v":4,"t":"I have no greater joy than this: to hear about my children walking in truth."},{"v":5,"t":"Beloved, you do a faithful work in whatever you accomplish for those who are brothers and strangers."},{"v":6,"t":"They have testified about your love before the assembly. You will do well to send them forward on their journey in a way worthy of God,"},{"v":7,"t":"because for the sake of the Name they went out, taking nothing from the Gentiles."},{"v":8,"t":"We therefore ought to receive such, that we may be fellow workers for the truth."},{"v":9,"t":"I wrote to the assembly, but Diotrephes, who loves to be first among them, doesn’t accept what we say."},{"v":10,"t":"Therefore, if I come, I will call attention to his deeds which he does, unjustly accusing us with wicked words. Not content with this, he doesn’t receive the brothers himself, and those who would, he forbids and throws out of the assembly."},{"v":11,"t":"Beloved, don’t imitate that which is evil, but that which is good. He who does good is of God. He who does evil hasn’t seen God."},{"v":12,"t":"Demetrius has the testimony of all, and of the truth itself; yes, we also testify, and you know that our testimony is true."},{"v":13,"t":"I had many things to write to you, but I am unwilling to write to you with ink and pen;"},{"v":14,"t":"but I hope to see you soon. Then we will speak face to face. Peace be to you. The friends greet you. Greet the friends by name."}],"hr":[{"v":1,"t":"Starješina ljubljenom Gaju koga ljubim u Istini."},{"v":2,"t":"Ljubljeni! Želim ti u svemu dobro i da budeš zdrav, kao što je dobro tvojoj duši."},{"v":3,"t":"Veoma se obradovah kada dođoše braća i posvjedočiše za tvoju istinu: kako ti živiš po Istini."},{"v":4,"t":"Čuti da moja djeca po Istini žive! - nema mi veće radosti od toga."},{"v":5,"t":"Ljubljeni, pravi si vjernik u svemu što činiš za braću, i to za došljake."},{"v":6,"t":"Oni posvjedočiše tvoju ljubav pred Crkvom i dobro ćeš učiniti ako ih ispratiš Boga dostojno."},{"v":7,"t":"Jer poradi Imena iziđoše i ne primaju ništa od pogana."},{"v":8,"t":"Mi smo dakle dužni takve primati da budemo suradnici Istine."},{"v":9,"t":"Pisao sam nešto Crkvi: ali Diotref, koji hoće da bude prvi među njima, ne prima nas."},{"v":10,"t":"Zato ako dođem, spočitnut ću mu djela koja čini naklapajući zlobne riječi o nama. Ni to mu nije dosta, nego ne prima braće, a onima koji bi to htjeli, brani i izgoni ih iz Crkve."},{"v":11,"t":"Ljubljeni! Ne nasljeduj zlo, nego dobro. Tko dobro čini, od Boga je; tko zlo čini, nije vidio Boga."},{"v":12,"t":"Za Demetrija svjedoče svi, i sama Istina, a i mi svjedočimo. A znaš da je naše svjedočanstvo istinito."},{"v":13,"t":"Mnogo bih ti imao pisati, ali neću da ti pišem crnilom i perom."},{"v":14,"t":"Nadam se da ću te uskoro vidjeti pa ćemo iz usta u usta govoriti."},{"v":15,"t":"Mir tebi! Pozdravljaju te prijatelji. Pozdravi prijatelje poimence."}]}},"JUD":{"1":{"fa":[{"v":1,"t":"یهودا، غلام عیسی مسیح و برادر یعقوب، به خوانده‌شدگانی که در خدای پدر حبیب وبرای عیسی مسیح محفوظ می‌باشید."},{"v":2,"t":"رحمت و سلامتی و محبت بر شما افزون باد."},{"v":3,"t":"‌ای حبیبان، چون شوق تمام داشتم که درباره نجات عام به شما بنویسم، ناچار شدم که الان به شما بنویسم و نصیحت دهم تا شما مجاهده کنیدبرای آن ایمانی که یک بار به مقدسین سپرده شد."},{"v":4,"t":"زیرا که بعضی اشخاص در خفا درآمده‌اند که ازقدیم برای این قصاص مقرر شده بودند؛ مردمان بی‌دین که فیض خدای ما را به فجور تبدیل نموده و عیسی مسیح آقای واحد و خداوند ما را انکارکرده‌اند."},{"v":5,"t":"پس می‌خواهم شما را یاد دهم، هرچند همه‌چیز را دفعه می‌دانید که بعد از آنکه خداوند، قوم را از زمین مصر رهایی بخشیده بود، بار دیگربی ایمانان را هلاک فرمود."},{"v":6,"t":"و فرشتگانی را که ریاست خود را حفظ نکردند بلکه مسکن حقیقی خود را ترک نمودند، در زنجیرهای ابدی درتحت ظلمت بجهت قصاص یوم عظیم نگاه داشته است."},{"v":7,"t":"و همچنین سدوم و غموره و سایربلدان نواحی آنها مثل ایشان چونکه زناکار شدند و در‌پی بشر دیگر افتادند، در عقوبت آتش ابدی گرفتار شده، بجهت عبرت مقرر شدند."},{"v":8,"t":"لیکن باوجود این، همه این خواب بینندگان نیز جسد خود را نجس می‌سازند و خداوندی راخوار می‌شمارند و بر بزرگان تهمت می‌زنند."},{"v":9,"t":"امامیکائیل، رئیس ملائکه، چون درباره جسدموسی با ابلیس منازعه می‌کرد، جرات ننمود که حکم افترا بر او بزند بلکه گفت: «خداوند تو راتوبیخ فرماید.»"},{"v":10,"t":"لکن این اشخاص بر آنچه نمی دانند افتراء می‌زنند و در آنچه مثل حیوان غیرناطق بالطبع فهمیده‌اند، خود را فاسدمی سازند."},{"v":11,"t":"وای بر ایشان زیرا که به راه قائن رفته‌اند ودر گمراهی بلعام بجهت اجرت غرق شده‌اند و درمشاجرت قورح هلاک گشته‌اند."},{"v":12,"t":"اینها درضیافت های محبتانه شما صخره‌ها هستند چون با شما شادی می‌کنند، و شبانانی که خویشتن رابی خوف می‌پرورند و ابرهای بی‌آب از بادهارانده شده و در ختان صیفی بی‌میوه، دوباره مرده و از ریشه‌کنده شده،"},{"v":13,"t":"و امواج جوشیده دریا که رسوایی خود را مثل کف برمی آورند و ستارگان آواره هستند که برای ایشان تاریکی ظلمت جاودانی مقرر است."},{"v":14,"t":"لکن خنوخ که هفتم ازآدم بود، درباره همین اشخاص خبر داده، گفت: «اینک خداوند با هزاران هزار از مقدسین خود یهودا آمد"},{"v":15,"t":"تا برهمه داوری نماید و جمیع بی‌دینان راملزم سازد، بر همه کارهای بی‌دینی که ایشان کردند و برتمامی سخنان زشت که گناهکاران بی‌دین به خلاف او گفتند.»"},{"v":16,"t":"اینانند همهمه‌کنان و گله‌مندان که برحسب شهوات خود سلوک می‌نمایند و به زبان خود سخنان تکبرآمیزمی گویند و صورتهای مردم را بجهت سودمی پسندند."},{"v":17,"t":"اما شما‌ای حبیبان، بخاطر آورید آن سخنانی که رسولان خداوند ما عیسی مسیح پیش گفته‌اند،"},{"v":18,"t":"چون به شما خبر دادند که در زمان آخر مستهزئین خواهند آمد که برحسب شهوات بی‌دینی خود رفتار خواهند کرد."},{"v":19,"t":"اینانند که تفرقه‌ها پیدا می‌کنند و نفسانی هستند که روح را ندارند."},{"v":20,"t":"اما شما‌ای حبیبان، خود را به ایمان اقدس خود بنا کرده و در روح‌القدس عبادت نموده،"},{"v":21,"t":"خویشتن را در محبت خدا محفوظ دارید ومنتظر رحمت خداوند ما عیسی مسیح برای حیات جاودانی بوده باشید."},{"v":22,"t":"و بعضی را که مجادله می‌کنند ملزم سازید."},{"v":23,"t":"و بعضی را ازآتش بیرون کشیده، برهانید و بر بعضی با خوف رحمت کنید و از لباس جسم آلود نفرت نمایید."},{"v":24,"t":"الان او را که قادر است که شما را از لغزش محفوظ دارد و در حضور جلال خود شما رابی عیب به فرحی عظیم قایم فرماید،"},{"v":25,"t":"یعنی خدای واحد و نجات‌دهنده ما را جلال و عظمت و توانایی و قدرت باد الان و تا ابدالاباد. آمین."}],"en":[{"v":1,"t":"Jude, a servant of Jesus Christ, and brother of James, to those who are called, sanctified by God the Father, and kept for Jesus Christ:"},{"v":2,"t":"May mercy, peace, and love be multiplied to you."},{"v":3,"t":"Beloved, while I was very eager to write to you about our common salvation, I was constrained to write to you exhorting you to contend earnestly for the faith which was once for all delivered to the saints."},{"v":4,"t":"For there are certain men who crept in secretly, even those who were long ago written about for this condemnation: ungodly men, turning the grace of our God into indecency, and denying our only Master, God, and Lord, Jesus Christ."},{"v":5,"t":"Now I desire to remind you, though you already know this, that the Lord, having saved a people out of the land of Egypt, afterward destroyed those who didn’t believe."},{"v":6,"t":"Angels who didn’t keep their first domain, but deserted their own dwelling place, he has kept in everlasting bonds under darkness for the judgment of the great day."},{"v":7,"t":"Even as Sodom and Gomorrah and the cities around them, having in the same way as these given themselves over to sexual immorality and gone after strange flesh, are shown as an example, suffering the punishment of eternal fire."},{"v":8,"t":"Yet in the same way, these also in their dreaming defile the flesh, despise authority, and slander celestial beings."},{"v":9,"t":"But Michael, the archangel, when contending with the devil and arguing about the body of Moses, dared not bring against him an abusive condemnation, but said, “May the Lord rebuke you!”"},{"v":10,"t":"But these speak evil of whatever things they don’t know. They are destroyed in these things that they understand naturally, like the creatures without reason."},{"v":11,"t":"Woe to them! For they went in the way of Cain, and ran riotously in the error of Balaam for hire, and perished in Korah’s rebellion."},{"v":12,"t":"These are hidden rocky reefs in your love feasts when they feast with you, shepherds who without fear feed themselves; clouds without water, carried along by winds; autumn trees without fruit, twice dead, plucked up by the roots;"},{"v":13,"t":"wild waves of the sea, foaming out their own shame; wandering stars, for whom the blackness of darkness has been reserved forever."},{"v":14,"t":"About these also Enoch, the seventh from Adam, prophesied, saying, “Behold, the Lord came with ten thousands of his holy ones,"},{"v":15,"t":"to execute judgment on all, and to convict all the ungodly of all their works of ungodliness which they have done in an ungodly way, and of all the hard things which ungodly sinners have spoken against him.”"},{"v":16,"t":"These are murmurers and complainers, walking after their lusts—and their mouth speaks proud things—showing respect of persons to gain advantage."},{"v":17,"t":"But you, beloved, remember the words which have been spoken before by the apostles of our Lord Jesus Christ."},{"v":18,"t":"They said to you, “In the last time there will be mockers, walking after their own ungodly lusts.”"},{"v":19,"t":"These are those who cause divisions and are sensual, not having the Spirit."},{"v":20,"t":"But you, beloved, keep building up yourselves on your most holy faith, praying in the Holy Spirit."},{"v":21,"t":"Keep yourselves in God’s love, looking for the mercy of our Lord Jesus Christ to eternal life."},{"v":22,"t":"On some have compassion, making a distinction,"},{"v":23,"t":"and some save, snatching them out of the fire with fear, hating even the clothing stained by the flesh."},{"v":24,"t":"Now to him who is able to keep them from stumbling, and to present you faultless before the presence of his glory in great joy,"},{"v":25,"t":"to God our Savior, who alone is wise, be glory and majesty, dominion and power, both now and forever. Amen."}],"hr":[{"v":1,"t":"Juda, sluga Isusa Krista, brat Jakovljev: ljubljenima u Bogu, Ocu, čuvanima za Isusa Krista - pozvanima."},{"v":2,"t":"Obilovali milošću, mirom i ljubavlju!"},{"v":3,"t":"Ljubljeni! Dok sam u svojoj brižljivosti kanio pisati vam o našem zajedničkom spasenju, osjetio sam potrebu da vas pismom potaknem da vojujete za vjeru koja je jednom zauvijek predana svetima."},{"v":4,"t":"Jer ušuljali se neki, odavna već zapisani za ovaj sud, bezbožnici koji milost Boga našega promeću u razuzdanost i niječu jedinoga gospodara i Gospodina našega Isusa Krista."},{"v":5,"t":"Želim vas podsjetiti, premda jednom zauvijek sve znate, kako je Gospodin izbavio narod iz Egipta, a zatim uništio nevjerne."},{"v":6,"t":"I anđele, koji nisu čuvali svojeg dostojanstva nego su ostavili svoje prebivalište, sačuvao je za sud velikoga Dana, okovane u mraku vječnim okovima;"},{"v":7,"t":"kao Sodoma i Gomora i okolni gradovi, koji su se poput njih podali bludu i otišli za drugom pÓuti, stoje za primjer, ispaštajući kaznu u vječnom ognju."},{"v":8,"t":"Uza sve to i ovi sanjari jednako skvrne tijelo, zabacuju Veličanstvo, pogrđuju Slave."},{"v":9,"t":"Kad se Mihael arkanđeo s đavlom prepirao za tijelo Mojsijevo, nije se usudio izreći pogrdan sud protiv njega, nego reče: “Spriječio te Gospodin!”"},{"v":10,"t":"A ovi pogrđuju ono što ne poznaju; a što po naravi kao nerazumne životinje poznaju, u tom trunu."},{"v":11,"t":"Jao njima! Putom Kajinovim pođoše, i zabludi se Bileamovoj za plaću podaše, i propadoše od pobune Korahove."},{"v":12,"t":"Oni su ljage na vašim agapama, bezobzirno se s vama gosteći i napasajući se; oblaci bezvodni što ih vjetrovi raznose, stabla besplodna u kasnoj jeseni, dvaput usahla, iskorijenjena,"},{"v":13,"t":"bijesno morsko valovlje što ispjenjuje svoje sramote, zvijezde lutalice kojima je spremljena crna tmina dovijeka."},{"v":14,"t":"O njima prorokova sedmi od Adama, Henok: “Gle, dođe Gospodin sa Desttisućama svojim"},{"v":15,"t":"suditi svima i pokarati sve bezbožnike za sva njihova bezbožna djela kojima bezbožno sagriješiše i za sve drzovite riječi koje grešni bezbožnici izrekoše protiv njega.”"},{"v":16,"t":"To su rogoborni nezadovoljnici koji hode putom svojih požuda, usta im zbore naduto, ulaguju se u lice radi dobitka."},{"v":17,"t":"A vi, ljubljeni, sjetite se riječi što ih prorekoše apostoli Gospodina našega Isusa Krista."},{"v":18,"t":"Oni vam govorahu: “U posljednje će vrijeme biti podrugljivaca koji će se povoditi za bezbožnim požudama svojim.”"},{"v":19,"t":"To su sijači razdora, sjetilnici koji nemaju Duha."},{"v":20,"t":"A vi, ljubljeni, naziđujte se na presvetoj vjeri svojoj moleći se u Duhu Svetom,"},{"v":21,"t":"uščuvajte se u ljubavi Božjoj, iščekujući milosrđe Gospodina našega Isusa Krista za vječni život."},{"v":22,"t":"I jedne, svadljivce, karajte,"},{"v":23,"t":"druge spasavajte otimajući ih ognju, trećima se pak smilujte sa strahom, mrzeći i haljinu puti okaljanu."},{"v":24,"t":"Onomu koji vas može očuvati od pada i besprijekorne postaviti pred svoju Slavu u klicanju -"},{"v":25,"t":"jedinomu Bogu, Spasitelju našemu, po Isusu Kristu, Gospodinu našemu: slava, veličanstvo, vlast i moć i prije svakoga vijeka, i sada, i u sve vijeke. Amen."}]}},"REV":{"1":{"fa":[{"v":1,"t":"مکاشفه عیسی مسیح که خدا به او داد تا اموری را که می‌باید زود واقع شود، برغلامان خود ظاهر سازد و بوسیله فرشته خودفرستاده، آن را ظاهر نمود بر غلام خود یوحنا،"},{"v":2,"t":"که گواهی داد به کلام خدا و به شهادت عیسی مسیح در اموری که دیده بود."},{"v":3,"t":"خوشابحال کسی‌که می‌خواند و آنانی که می‌شنوند کلام این نبوت را، و آنچه در این مکتوب است نگاه می‌دارند، چونکه وقت نزدیک است."},{"v":4,"t":"یوحنا، به هفت کلیسایی که در آسیا هستند."},{"v":5,"t":"و از عیسی مسیح که شاهد امین ونخست زاده از مردگان و رئیس پادشاهان جهان است. مر او را که ما را محبت می‌نماید و ما را ازگناهان ما به خون خود شست،"},{"v":6,"t":"و ما را نزد خدا وپدر خود پادشاهان و کهنه ساخت، او را جلال وتوانایی باد تا ابدالاباد. آمین."},{"v":7,"t":"اینک با ابرها می‌آید و هر چشمی او راخواهد دید و آنانی که او را نیزه زدند و تمامی امت های جهان برای وی خواهند نالید. بلی!"},{"v":8,"t":"«من هستم الف و یا، اول و آخر، » می‌گویدآن خداوند خدا که هست و بود و می‌آید، قادرعلی الاطلاق."},{"v":9,"t":"من یوحنا که برادر شما و شریک در مصیبت و ملکوت و صبر در عیسی مسیح هستم، بجهت کلام خدا و شهادت عیسی مسیح در جزیره‌ای مسمی به پطمس شدم."},{"v":10,"t":"و در روز خداوند درروح شدم و از عقب خود آوازی بلند چون صدای صور شنیدم،"},{"v":11,"t":"که می‌گفت: «من الف و یاو اول و آخر هستم. آنچه می‌بینی در کتابی بنویس و آن را به هفت کلیسایی که در آسیاهستند، یعنی به افسس و اسمیرنا و پرغامس وطیاتیرا و ساردس و فیلادلفیه و لائودکیه بفرست.»"},{"v":12,"t":"پس رو برگردانیدم تا آن آوازی را که با من تکلم می‌نمود بنگرم؛ و چون رو گردانیدم، هفت چراغدان طلا دیدم،"},{"v":13,"t":"و در میان هفت چراغدان، شبیه پسر انسان را که ردای بلند در بر داشت و برسینه وی کمربندی طلا بسته بود،"},{"v":14,"t":"و سر و موی او سفید چون پشم، مثل برف سفید بود و چشمان او مثل شعله آتش،"},{"v":15,"t":"و پایهایش مانند برنج صیقلی که در کوره تابیده شود، و آواز او مثل صدای آبهای بسیار؛"},{"v":16,"t":"و در دست راست خود هفت ستاره داشت و از دهانش شمشیری دودمه تیز بیرون می‌آمد و چهره‌اش چون آفتاب بود که در قوتش می‌تابد."},{"v":17,"t":"و چون او را دیدم، مثل مرده پیش پایهایش افتادم و دست راست خود را بر من نهاده، گفت: «ترسان مباش! من هستم اول و آخر و زنده؛"},{"v":18,"t":"ومرده شدم و اینک تا ابدالاباد زنده هستم وکلیدهای موت و عالم اموات نزد من است."},{"v":19,"t":"پس بنویس چیزهایی را که دیدی و چیزهایی که هستند و چیزهایی را که بعد از این خواهند شد،"},{"v":20,"t":"سر هفت ستاره‌ای را که در دست راست من دیدی و هفت چراغدان طلا را. اما هفت ستاره، فرشتگان هفت کلیسا هستند و هفت چراغدان، هفت کلیسا می‌باشند."}],"en":[{"v":1,"t":"This is the Revelation of Jesus Christ, which God gave him to show to his servants the things which must happen soon, which he sent and made known by his angel to his servant, John,"},{"v":2,"t":"who testified to God’s word and of the testimony of Jesus Christ, about everything that he saw."},{"v":3,"t":"Blessed is he who reads and those who hear the words of the prophecy, and keep the things that are written in it, for the time is near."},{"v":4,"t":"John, to the seven assemblies that are in Asia: Grace to you and peace from God, who is and who was and who is to come; and from the seven Spirits who are before his throne;"},{"v":5,"t":"and from Jesus Christ, the faithful witness, the firstborn of the dead, and the ruler of the kings of the earth. To him who loves us, and washed us from our sins by his blood—"},{"v":6,"t":"and he made us to be a Kingdom, priests to his God and Father—to him be the glory and the dominion forever and ever. Amen."},{"v":7,"t":"Behold, he is coming with the clouds, and every eye will see him, including those who pierced him. All the tribes of the earth will mourn over him. Even so, Amen."},{"v":8,"t":"“I am the Alpha and the Omega,” says the Lord God, “who is and who was and who is to come, the Almighty.”"},{"v":9,"t":"I John, your brother and partner with you in the oppression, Kingdom, and perseverance in Christ Jesus, was on the isle that is called Patmos because of God’s Word and the testimony of Jesus Christ."},{"v":10,"t":"I was in the Spirit on the Lord’s day, and I heard behind me a loud voice, like a trumpet"},{"v":11,"t":"saying, “What you see, write in a book and send to the seven assemblies: to Ephesus, Smyrna, Pergamum, Thyatira, Sardis, Philadelphia, and to Laodicea.”"},{"v":12,"t":"I turned to see the voice that spoke with me. Having turned, I saw seven golden lamp stands."},{"v":13,"t":"And among the lamp stands was one like a son of man, clothed with a robe reaching down to his feet, and with a golden sash around his chest."},{"v":14,"t":"His head and his hair were white as white wool, like snow. His eyes were like a flame of fire."},{"v":15,"t":"His feet were like burnished brass, as if it had been refined in a furnace. His voice was like the voice of many waters."},{"v":16,"t":"He had seven stars in his right hand. Out of his mouth proceeded a sharp two-edged sword. His face was like the sun shining at its brightest."},{"v":17,"t":"When I saw him, I fell at his feet like a dead man. He laid his right hand on me, saying, “Don’t be afraid. I am the first and the last,"},{"v":18,"t":"and the Living one. I was dead, and behold, I am alive forever and ever. Amen. I have the keys of Death and of Hades."},{"v":19,"t":"Write therefore the things which you have seen, and the things which are, and the things which will happen hereafter."},{"v":20,"t":"The mystery of the seven stars which you saw in my right hand, and the seven golden lamp stands is this: The seven stars are the angels of the seven assemblies. The seven lamp stands are seven assemblies."}],"hr":[{"v":1,"t":"Otkrivenje Isusa Krista: njemu ga dade Bog da on pokaže slugama svojim ono što se ima dogoditi ubrzo. I on to označi poslavši svog anđela sluzi svomu Ivanu"},{"v":2,"t":"koji posvjedoči za riječ Božju i za svjedočanstvo Isusa Krista - za sve što vidje."},{"v":3,"t":"Blago onomu koji čita i onima što slušaju riječi ovog proroštva te čuvaju što je u njem napisano. Jer vrijeme je blizu!"},{"v":4,"t":"Ivan sedmerim crkvama u Aziji. Milost vam i mir od Onoga koji jest i koji bijaše i koji dolazi i od sedam duhova što su pred Prijestoljem njegovim"},{"v":5,"t":"i od Isusa Krista, Svjedoka vjernoga, Prvorođenca od mrtvih, Vladara nad kraljevima zemaljskim. Njemu koji nas ljubi, koji nas krvlju svojom otkupi od naših grijeha"},{"v":6,"t":"te nas učini kraljevstvom, svećenicima Bogu i Ocu svojemu: Njemu slava i vlast u vijeke vjekova! Amen!"},{"v":7,"t":"Gle, dolazi s oblacima i gledat će ga svako oko, svi koji su ga proboli, i naricat će nad njim sva plemena zemaljska. Da! Amen."},{"v":8,"t":"Ja sam Alfa i Omega, govori Gospodin Bog - Onaj koji jest i koji bijaše i koji dolazi, Svevladar."},{"v":9,"t":"Ja, Ivan, brat vaš i suzajedničar u nevolji, kraljevstvu i postojanosti, u Isusu: bijah na otoku zvanu Patmos radi riječi Božje i svjedočanstva Isusova."},{"v":10,"t":"Zanijeh se u duhu u dan Gospodnji i začuh iza sebe jak glas, kao glas trublje."},{"v":11,"t":"Govoraše: “Što vidiš, napiši u knjigu i pošalji sedmerim crkvama: U Efez, Smirnu, Pergam, Tijatiru, Sard, Filadelfiju, Laodiceju.”"},{"v":12,"t":"Okrenuh se da vidim glas koji govoraše sa mnom. I okrenuvši se, vidjeh sedam zlatnih svijećnjaka,"},{"v":13,"t":"a posred svijećnjaka netko kao Sin Čovječji, odjeven u dugu haljinu, oko prsiju opasan zlatnim pojasom;"},{"v":14,"t":"glava mu i vlasi bijele poput bijele vune, poput snijega, a oči mu kao plamen ognjeni;"},{"v":15,"t":"noge mu nalik mjedi uglađenoj, kao u peći užarenoj, a glas mu kao šum voda mnogih;"},{"v":16,"t":"u desnici mu sedam zvijezda, iz usta mu izlazi mač dvosječan, oštar, a lice mu kao kad sunce sjaji u svoj svojoj snazi."},{"v":17,"t":"Kad ga vidjeh, padoh mu k nogama kao mrtav. A on stavi na me desnicu govoreći: “Ne boj se! Ja sam Prvi i Posljednji,"},{"v":18,"t":"i Živi! Mrtav bijah, a evo živim u vijeke vjekova te imam ključe Smrti, i Podzemlja."},{"v":19,"t":"Napiši dakle što si vidio: ono što jest i što se ima dogoditi poslije."},{"v":20,"t":"Glede tajne onih sedam zvijezda koje vidje u mojoj desnici i sedam zlatnih svijećnjaka: sedam zvijezda anđeli su sedam crkava, sedam svijećnjaka sedam je crkava.”"}]},"2":{"fa":[{"v":1,"t":"«به فرشته کلیسای در افسس بنویس که این را می‌گوید او که هفت ستاره را بدست راست خود دارد و در میان هفت چراغدان طلامی خرامد."},{"v":2,"t":"می‌دانم اعمال تو را و مشقت و صبرتو را و اینکه متحمل اشرار نمی توانی شد و آنانی را که خود را رسولان می‌خوانند و نیستندآزمودی و ایشان را دروغگو یافتی؛"},{"v":3,"t":"و صبرداری و بخاطر اسم من تحمل کردی و خسته نگشتی."},{"v":4,"t":"«لکن بحثی بر تو دارم که محبت نخستین خود را ترک کرده‌ای."},{"v":5,"t":"پس بخاطر آر که از کجاافتاده‌ای و توبه کن و اعمال نخست را بعمل آوروالا بزودی نزد تو می‌آیم و چراغدانت را از مکانش نقل می‌کنم اگر توبه نکنی."},{"v":6,"t":"لکن این راداری که اعمال نقولاویان را دشمن داری، چنانکه من نیز از آنها نفرت دارم."},{"v":7,"t":"«آنکه گوش دارد بشنود که روح به کلیساهاچه می‌گوید: هر‌که غالب آید، به او این را خواهم بخشید که از درخت حیاتی که در وسط فردوس خداست بخورد."},{"v":8,"t":"«و به فرشته کلیسای در اسمیرنا بنویس که این را می‌گوید آن اول و آخر که مرده شد و زنده گشت."},{"v":9,"t":"اعمال و تنگی و مفلسی تو را می‌دانم، لکن دولتمند هستی و کفر آنانی را که خود رایهود می‌گویند و نیستند بلکه از کنیسه شیطانند."},{"v":10,"t":"از آن زحماتی که خواهی کشید مترس. اینک ابلیس بعضی از شما را در زندان خواهد انداخت تا تجربه کرده شوید و مدت ده روز زحمت خواهید کشید. لکن تا به مرگ امین باش تا تاج حیات را به تو دهم."},{"v":11,"t":"آنکه گوش دارد بشنود که روح به کلیساها چه می‌گوید: هر‌که غالب آید ازموت ثانی ضرر نخواهد یافت."},{"v":12,"t":"«و به فرشته کلیسای در پرغامس بنویس این را می‌گوید او که شمشیر دودمه تیز را دارد."},{"v":13,"t":"اعمال و مسکن تو را می‌دانم که تخت شیطان در آنجاست و اسم مرا محکم داری و ایمان مراانکار ننمودی، نه هم در ایامی که انطیپاس شهیدامین من در میان شما در جایی که شیطان ساکن است کشته شد."},{"v":14,"t":"لکن بحث کمی بر تو دارم که در آنجا اشخاصی را داری که متمسکند به تعلیم بلعام که بالاق را آموخت که در راه بنی‌اسرائیل سنگی مصادم بیندازد تا قربانی های بتها رابخورند و زنا کنند."},{"v":15,"t":"و همچنین کسانی را داری که تعلیم نقولاویان را پذیرفته‌اند."},{"v":16,"t":"پس توبه کن والا بزودی نزد تو می‌آیم و به شمشیر زبان خود باایشان جنگ خواهم کرد."},{"v":17,"t":"آنکه گوش دارد، بشنود که روح به کلیساها چه می‌گوید: و آنکه غالب آید، از من مخفی به وی خواهم داد وسنگی سفید به او خواهم بخشید که بر آن سنگ اسمی جدید مرقوم است که احدی آن رانمی داند جز آنکه آن را یافته باشد."},{"v":18,"t":"«و به فرشته کلیسای در طیاتیرا بنویس این را می‌گوید پسر خدا که چشمان او چون شعله آتش و پایهای او چون برنج صیقلی است."},{"v":19,"t":"اعمال و محبت و خدمت و ایمان و صبر تو رامی دانم و اینکه اعمال آخر تو بیشتر از اول است."},{"v":20,"t":"لکن بحثی بر تو دارم که آن زن ایزابل نامی راراه می‌دهی که خود را نبیه می‌گوید و بندگان مراتعلیم داده، اغوا می‌کند که مرتکب زنا و خوردن قربانی های بتها بشوند."},{"v":21,"t":"و به او مهلت دادم تاتوبه کند، اما نمی خواهد از زنای خود توبه کند."},{"v":22,"t":"اینک او را بر بستری می‌اندازم و آنانی را که بااو زنا می‌کنند، به مصیبتی سخت مبتلا می‌گردانم اگر از اعمال خود توبه نکنند،"},{"v":23,"t":"و اولادش را به قتل خواهم رسانید. آنگاه همه کلیساها خواهنددانست که منم امتحان کننده جگرها و قلوب و هریکی از شما را برحسب اعمالش خواهم داد."},{"v":24,"t":"لکن باقی ماندگان شما را که در طیاتیرا هستیدو این تعلیم را نپذیرفته‌اید و عمقهای شیطان راچنانکه می‌گویند نفهمیده‌اید، بار دیگری بر شمانمی گذارم،"},{"v":25,"t":"جز آنکه به آنچه دارید تا هنگام آمدن من تمسک جویید."},{"v":26,"t":"و هر‌که غالب آید واعمال مرا تا انجام نگاه دارد، او را بر امت هاقدرت خواهم بخشید"},{"v":27,"t":"تا ایشان را به عصای آهنین حکمرانی کند و مثل کوزه های کوزه‌گرخرد خواهند شد، چنانکه من نیز از پدر خودیافته‌ام."},{"v":28,"t":"و به او ستاره صبح را خواهم بخشید."},{"v":29,"t":"آنکه گوش دارد بشنود که روح به کلیساها چه می‌گوید."}],"en":[{"v":1,"t":"“To the angel of the assembly in Ephesus write: “He who holds the seven stars in his right hand, he who walks among the seven golden lamp stands says these things:"},{"v":2,"t":"“I know your works, and your toil and perseverance, and that you can’t tolerate evil men, and have tested those who call themselves apostles, and they are not, and found them false."},{"v":3,"t":"You have perseverance and have endured for my name’s sake, and have not grown weary."},{"v":4,"t":"But I have this against you, that you left your first love."},{"v":5,"t":"Remember therefore from where you have fallen, and repent and do the first works; or else I am coming to you swiftly, and will move your lamp stand out of its place, unless you repent."},{"v":6,"t":"But this you have, that you hate the works of the Nicolaitans, which I also hate."},{"v":7,"t":"He who has an ear, let him hear what the Spirit says to the assemblies. To him who overcomes I will give to eat from the tree of life, which is in the Paradise of my God."},{"v":8,"t":"“To the angel of the assembly in Smyrna write: “The first and the last, who was dead, and has come to life says these things:"},{"v":9,"t":"“I know your works, oppression, and your poverty (but you are rich), and the blasphemy of those who say they are Jews, and they are not, but are a synagogue of Satan."},{"v":10,"t":"Don’t be afraid of the things which you are about to suffer. Behold, the devil is about to throw some of you into prison, that you may be tested; and you will have oppression for ten days. Be faithful to death, and I will give you the crown of life."},{"v":11,"t":"He who has an ear, let him hear what the Spirit says to the assemblies. He who overcomes won’t be harmed by the second death."},{"v":12,"t":"“To the angel of the assembly in Pergamum write: “He who has the sharp two-edged sword says these things:"},{"v":13,"t":"“I know your works and where you dwell, where Satan’s throne is. You hold firmly to my name, and didn’t deny my faith in the days of Antipas my witness, my faithful one, who was killed among you, where Satan dwells."},{"v":14,"t":"But I have a few things against you, because you have there some who hold the teaching of Balaam, who taught Balak to throw a stumbling block before the children of Israel, to eat things sacrificed to idols, and to commit sexual immorality."},{"v":15,"t":"So also you likewise have some who hold to the teaching of the Nicolaitans."},{"v":16,"t":"Repent therefore, or else I am coming to you quickly and I will make war against them with the sword of my mouth."},{"v":17,"t":"He who has an ear, let him hear what the Spirit says to the assemblies. To him who overcomes, to him I will give of the hidden manna, and I will give him a white stone, and on the stone a new name written which no one knows but he who receives it."},{"v":18,"t":"“To the angel of the assembly in Thyatira write: “The Son of God, who has his eyes like a flame of fire, and his feet are like burnished brass, says these things:"},{"v":19,"t":"“I know your works, your love, faith, service, patient endurance, and that your last works are more than the first."},{"v":20,"t":"But I have this against you, that you tolerate your woman Jezebel, who calls herself a prophetess. She teaches and seduces my servants to commit sexual immorality and to eat things sacrificed to idols."},{"v":21,"t":"I gave her time to repent, but she refuses to repent of her sexual immorality."},{"v":22,"t":"Behold, I will throw her and those who commit adultery with her into a bed of great oppression, unless they repent of her works."},{"v":23,"t":"I will kill her children with Death, and all the assemblies will know that I am he who searches the minds and hearts. I will give to each one of you according to your deeds."},{"v":24,"t":"But to you I say, to the rest who are in Thyatira—as many as don’t have this teaching, who don’t know what some call ‘the deep things of Satan’—to you I say, I am not putting any other burden on you."},{"v":25,"t":"Nevertheless, hold that which you have firmly until I come."},{"v":26,"t":"He who overcomes, and he who keeps my works to the end, to him I will give authority over the nations."},{"v":27,"t":"He will rule them with a rod of iron, shattering them like clay pots, as I also have received of my Father;"},{"v":28,"t":"and I will give him the morning star."},{"v":29,"t":"He who has an ear, let him hear what the Spirit says to the assemblies."}],"hr":[{"v":1,"t":"Anđelu Crkve u Efezu napiši: “Ovo govori Onaj koji drži sedam zvijezda u desnici, Onaj koji stupa posred sedam zlatnih svijećnjaka:"},{"v":2,"t":"Znam tvoja djela, tvoj trud i postojanost tvoju i da ne možeš podnijeti opakih. Iskušao si one koji se prave apostolima, a nisu, i otkrio si da su lažljivci."},{"v":3,"t":"Postojan si, podnio si za ime moje i nisi smalaksao."},{"v":4,"t":"Ali imam protiv tebe: prvu si ljubav svoju ostavio."},{"v":5,"t":"Spomeni se dakle odakle si pao, obrati se i čini prva djela. Inače dolazim k tebi i - uklonit ću tvoj svijećnjak s mjesta njegova ako se ne obratiš."},{"v":6,"t":"Ali ovo imaš: mrziš nikolaitska djela koja i ja mrzim.”"},{"v":7,"t":"“Tko ima uho, nek posluša što Duh govori crkvama! Pobjedniku ću dati jesti od stabla života koje je u raju Božjem.”"},{"v":8,"t":"I anđelu Crkve u Smirni napiši: “Ovo govori Prvi i Posljednji, Onaj koji bijaše mrtav i oživje:"},{"v":9,"t":"Znam tvoju nevolju i siromaštvo - ali ti si bogat! - i pogrde od onih koji se nazivaju Židovima, a nisu, nego su sinagoga Sotonina."},{"v":10,"t":"Ne boj se onoga što ti je trpjeti! Evo, Sotona, će neke od vas baciti u tamnicu da budete iskušani. Bit ćete u nevolji deset dana. Budi vjeran do smrti i dat ću ti vijenac života.”"},{"v":11,"t":"“Tko ima uho, nek posluša što Duh govori crkvama! Pobjedniku neće nauditi druga smrt.”"},{"v":12,"t":"I anđelu Crkve u Pergamu napiši: “Ovo govori Onaj u koga je mač dvosjek, oštar:"},{"v":13,"t":"Znam gdje prebivaš - ondje gdje je Sotonino prijestolje - a čvrsto se držiš moga imena te nisi zanijekao moje vjere ni u one dane kad je Antipa, moj svjedok, vjerni moj, ubijen kod vas - gdje Sotona prebiva."},{"v":14,"t":"Ali imam nešto malo protiv tebe: imaš ondje nekih što drže nauk Bileama što pouči Balaka da stupicu stavi sinovima Izraelovim te blaguju od mesa žrtvovana idolima i bludu se podadu."},{"v":15,"t":"Tako i ti imaš takvih koji drže nauk nikolaitski."},{"v":16,"t":"Obrati se dakle! Inače dolazim ubrzo k tebi da ratujem s njima mačem usta svojih.”"},{"v":17,"t":"“Tko ima uho, nek posluša što Duh govori crkvama! Pobjedniku ću dati mane sakrivene i bijel ću mu kamen dati, a na kamenu napisano ime novo koje nitko ne zna doli onaj koji ga prima.”"},{"v":18,"t":"I anđelu Crkve u Tijatiri napiši: “Ovo govori Sin Božji, Onaj u koga su oči kao plamen ognjeni, a noge mu nalik na mjed uglađenu:"},{"v":19,"t":"Znam tvoja djela: tvoju ljubav, i vjeru, i služenje, i postojanost - i tvoja posljednja djela obilatija od prvašnjih."},{"v":20,"t":"Ali imam protiv tebe: puštaš ženu Jezabelu, koja se pravi proročicom, da uči i zavodi moje sluge te se bludu podaju i blaguju od mesa žrtvovana idolima."},{"v":21,"t":"Dadoh joj vremena za obraćenje, ali ona neće da se obrati od bludnosti svoje."},{"v":22,"t":"Evo, bacam je na postelju, a bludne drugare njene u veliku nevolju ako se ne odvrate od njezinih djela;"},{"v":23,"t":"i djecu ću joj smrću pobiti. I znat će sve crkve: Ja sam Onaj koji istražuje bubrege i srca - i dat ću vam svakomu po djelima."},{"v":24,"t":"Vama pak velim - vama drugim u Tijatiri koji ne drže ovog nauka te ne upoznaše takozvanih dubina sotonskih: Ne stavljam na vas drugoga bremena"},{"v":25,"t":"nego - što imate, čvrsto držite dok ne dođem.”"},{"v":26,"t":"“Pobjedniku, onomu što do kraja bude vršio moja djela, dat ću vlast nad narodima"},{"v":27,"t":"i vladat će njima palicom gvozdenom, kao posuđe glineno satirati ih -"},{"v":28,"t":"kao što i ja to primih od Oca svoga. I dat ću mu zvijezdu Danicu."},{"v":29,"t":"Tko ima uho, nek posluša što Duh govori crkvama!”"}]},"3":{"fa":[{"v":1,"t":"«و به فرشته کلیسای در ساردس بنویس این را می‌گوید او که هفت روح خدا و هفت ستاره را دارد. اعمال تو را می‌دانم که نام داری که زنده‌ای ولی مرده هستی."},{"v":2,"t":"بیدار شو و مابقی را که نزدیک به فنا است، استوار نما زیرا که هیچ عمل تو را در حضور خدا کامل نیافتم."},{"v":3,"t":"پس بیاد آورچگونه یافته‌ای و شنیده‌ای و حفظ کن و توبه نمازیرا هرگاه بیدار نباشی، مانند دزد بر تو خواهم آمد و از ساعت آمدن من بر تو مطلع نخواهی شد."},{"v":4,"t":"«لکن در ساردس اسمهای چند داری که لباس خود را نجس نساخته‌اند و در لباس سفید با من خواهند خرامید زیرا که مستحق هستند."},{"v":5,"t":"هرکه غالب آید به‌جامه سفید ملبس خواهد شد واسم او را از دفتر حیات محو نخواهم ساخت بلکه به نام وی در حضور پدرم و فرشتگان او اقرارخواهم نمود."},{"v":6,"t":"آنکه گوش دارد بشنود که روح به کلیساها چه می‌گوید."},{"v":7,"t":"«و به فرشته کلیسای در فیلادلفیه بنویس که این را می‌گوید آن قدوس و حق که کلید داود رادارد که می‌گشاید و هیچ‌کس نخواهد بست ومی بندد و هیچ‌کس نخواهد گشود."},{"v":8,"t":"اعمال تو رامی دانم. اینک دری گشاده پیش روی تو گذارده‌ام که کسی آن را نتواند بست، زیرا اندک قوتی داری و کلام مرا حفظ کرده، اسم مرا انکار ننمودی."},{"v":9,"t":"اینک می‌دهم آنانی را از کنیسه شیطان که خودرا یهود می‌نامند و نیستند بلکه دروغ می‌گویند. اینک ایشان را مجبور خواهم نمود که بیایند وپیش پایهای تو سجده کنند و بدانند که من تو رامحبت نموده‌ام."},{"v":10,"t":"چونکه کلام صبر مرا حفظنمودی، من نیز تو را محفوظ خواهم داشت، ازساعت امتحان که بر تمام ربع مسکون خواهد آمدتا تمامی ساکنان زمین را بیازماید."},{"v":11,"t":"بزودی می‌آیم، پس آنچه داری حفظ کن مبادا کسی تاج تو را بگیرد."},{"v":12,"t":"هر‌که غالب آید، او را در هیکل خدای خود ستونی خواهم ساخت و دیگر هرگزبیرون نخواهد رفت و نام خدای خود را و نام شهرخدای خود یعنی اورشلیم جدید را که از آسمان از جانب خدای من نازل می‌شود و نام جدید خودرا بر وی خواهم نوشت."},{"v":13,"t":"آنکه گوش داردبشنود که روح به کلیساها چه می‌گوید."},{"v":14,"t":"«و به فرشته کلیسای در لائودکیه بنویس که این را می‌گوید آمین و شاهد امین و صدیق که ابتدای خلقت خداست."},{"v":15,"t":"اعمال تو را می‌دانم که نه سرد و نه گرم هستی. کاشکه سرد بودی یاگرم."},{"v":16,"t":"لهذا چون فاتر هستی یعنی نه گرم و نه سرد، تو را از دهان خود قی خواهم کرد."},{"v":17,"t":"زیرامی گویی دولتمند هستم و دولت اندوخته‌ام و به هیچ‌چیز محتاج نیستم و نمی دانی که تو مستمندو مسکین هستی و فقیر و کور و عریان."},{"v":18,"t":"تو رانصیحت می‌کنم که زر مصفای به آتش را از من بخری تا دولتمند شوی، و رخت سفید را تاپوشانیده شوی و ننگ عریانی تو ظاهر نشود وسرمه را تا به چشمان خود کشیده بینایی یابی."},{"v":19,"t":"هر‌که را من دوست می‌دارم، توبیخ وتادیب می‌نمایم. پس غیور شو و توبه نما."},{"v":20,"t":"اینک بر در ایستاده می‌کوبم؛ اگر کسی آوازمرا بشنود و در را باز کند، به نزد او درخواهم آمد و با وی شام خواهم خورد و او نیز با من."},{"v":21,"t":"آنکه غالب آید، این را به وی خواهم داد که بر تخت من با من بنشیند، چنانکه من غلبه یافتم و با پدر خود بر تخت او نشستم."},{"v":22,"t":"هر‌که گوش دارد بشنود که روح به کلیساها چه می‌گوید.»"}],"en":[{"v":1,"t":"“And to the angel of the assembly in Sardis write: “He who has the seven Spirits of God and the seven stars says these things: “I know your works, that you have a reputation of being alive, but you are dead."},{"v":2,"t":"Wake up and strengthen the things that remain, which you were about to throw away, for I have found no works of yours perfected before my God."},{"v":3,"t":"Remember therefore how you have received and heard. Keep it and repent. If therefore you won’t watch, I will come as a thief, and you won’t know what hour I will come upon you."},{"v":4,"t":"Nevertheless you have a few names in Sardis that didn’t defile their garments. They will walk with me in white, for they are worthy."},{"v":5,"t":"He who overcomes will be arrayed in white garments, and I will in no way blot his name out of the book of life, and I will confess his name before my Father, and before his angels."},{"v":6,"t":"He who has an ear, let him hear what the Spirit says to the assemblies."},{"v":7,"t":"“To the angel of the assembly in Philadelphia write: “He who is holy, he who is true, he who has the key of David, he who opens and no one can shut, and who shuts and no one opens, says these things:"},{"v":8,"t":"“I know your works (behold, I have set before you an open door, which no one can shut), that you have a little power, and kept my word, and didn’t deny my name."},{"v":9,"t":"Behold, I make some of the synagogue of Satan, of those who say they are Jews, and they are not, but lie—behold, I will make them to come and worship before your feet, and to know that I have loved you."},{"v":10,"t":"Because you kept my command to endure, I also will keep you from the hour of testing which is to come on the whole world, to test those who dwell on the earth."},{"v":11,"t":"I am coming quickly! Hold firmly that which you have, so that no one takes your crown."},{"v":12,"t":"He who overcomes, I will make him a pillar in the temple of my God, and he will go out from there no more. I will write on him the name of my God and the name of the city of my God, the new Jerusalem, which comes down out of heaven from my God, and my own new name."},{"v":13,"t":"He who has an ear, let him hear what the Spirit says to the assemblies."},{"v":14,"t":"“To the angel of the assembly in Laodicea write: “The Amen, the Faithful and True Witness, the Beginning of God’s creation, says these things:"},{"v":15,"t":"“I know your works, that you are neither cold nor hot. I wish you were cold or hot."},{"v":16,"t":"So, because you are lukewarm, and neither hot nor cold, I will vomit you out of my mouth."},{"v":17,"t":"Because you say, ‘I am rich, and have gotten riches, and have need of nothing,’ and don’t know that you are the wretched one, miserable, poor, blind, and naked;"},{"v":18,"t":"I counsel you to buy from me gold refined by fire, that you may become rich; and white garments, that you may clothe yourself, and that the shame of your nakedness may not be revealed; and eye salve to anoint your eyes, that you may see."},{"v":19,"t":"As many as I love, I reprove and chasten. Be zealous therefore, and repent."},{"v":20,"t":"Behold, I stand at the door and knock. If anyone hears my voice and opens the door, then I will come in to him and will dine with him, and he with me."},{"v":21,"t":"He who overcomes, I will give to him to sit down with me on my throne, as I also overcame and sat down with my Father on his throne."},{"v":22,"t":"He who has an ear, let him hear what the Spirit says to the assemblies.”"}],"hr":[{"v":1,"t":"I anđelu Crkve u Sardu napiši: “Ovo govori Onaj koji ima sedam duhova Božjih i sedam zvijezda: Znam tvoja djela: imaš ime da živiš, a mrtav si."},{"v":2,"t":"Budan budi i utvrdi ostatak koji tek što ne umre. Doista, ne nađoh da su ti djela pred Bogom mojim savršena."},{"v":3,"t":"Spomeni se dakle: kako si primio Riječ i poslušao, tako je i čuvaj - i obrati se. Ne budeš li dakle budan, doći ću kao tat, a nećeš znati u koji ću čas doći na te."},{"v":4,"t":"Ali imaš u Sardu nekolicinu imena što ne okaljaše svojih haljina; oni će hoditi sa mnom u bjelini jer su dostojni.”"},{"v":5,"t":"“Tako će pobjednik biti odjeven u bijele haljine i neću izbrisati imena njegova iz knjige života i priznat ću ime njegovo pred Ocem svojim i anđelima njegovim.”"},{"v":6,"t":"“Tko ima uho, nek posluša što Duh govori crkvama!”"},{"v":7,"t":"I anđelu Crkve u Filadelfiji napiši: “Ovo govori Sveti, Istiniti, Onaj koji ima ključ Davidov i kad otvori, nitko neće zatvoriti; kad zatvori, nitko neće otvoriti:"},{"v":8,"t":"Znam tvoja djela. Evo, otvorio sam pred tobom vrata kojih nitko zatvoriti ne može. Doista, malena je tvoja snaga, a očuvao si moju riječ i nisi zatajio mog imena."},{"v":9,"t":"Evo, dovest ću neke iz sinagoge Sotonine - koji sebe zovu Židovi, a nisu, nego lažu - evo, prisilit ću ih da dođu da ti se do nogu poklone te upoznaju da te ja ljubim."},{"v":10,"t":"Budući da si očuvao moju riječ o postojanosti, i ja ću očuvati tebe od časa kušnje koji ima doći na sav svijet da se iskušaju svi pozemljari."},{"v":11,"t":"Dolazim ubrzo. Čvrsto drži što imaš da ti nitko ne ugrabi vijenca.”"},{"v":12,"t":"“Pobjednika ću postaviti stupom u hramu Boga moga i odande on više neće izići i napisat ću na njemu ime Boga svoga i ime grada Boga svoga, novog Jeruzalema koji siđe s neba od Boga mojega, i ime moje novo.”"},{"v":13,"t":"“Tko ima uho, nek posluša što Duh govori crkvama!”"},{"v":14,"t":"I anđelu Crkve u Laodiceji napiši: “Ovo govori Amen, Svjedok vjerni i istiniti, Početak Božjeg stvorenja:"},{"v":15,"t":"Znam tvoja djela: nisi ni studen ni vruć. O da si studen ili vruć!"},{"v":16,"t":"Ali jer si mlak, ni vruć ni studen, povratit ću te iz usta."},{"v":17,"t":"Govoriš: 'Bogat sam, obogatih se, ništa mi ne treba!' A ne znaš da si nevolja i bijeda, i ubog, i slijep, i gol."},{"v":18,"t":"Savjetujem ti: kupi od mene zlata u vatri žežena da se obogatiš i bijele haljine da se odjeneš da se ne vidi tvoja sramotna golotinja; i pomasti da oči pomažeš i vidiš."},{"v":19,"t":"Ja korim i odgajam one koje ljubim. Revan budi i obrati se!"},{"v":20,"t":"Evo, na vratima stojim i kucam; posluša li tko glas moj i otvori mi vrata, unići ću k njemu i večerati s njim i on sa mnom.”"},{"v":21,"t":"“Pobjednika ću posjesti sa sobom na prijestolje svoje, kao što i ja, pobijedivši, sjedoh s Ocem svojim na prijestolje njegovo.”"},{"v":22,"t":"“Tko ima uho, nek posluša što Duh govori crkvama!”"}]},"4":{"fa":[{"v":1,"t":"بعد از این دیدم که ناگاه دروازه‌ای درآسمان باز شده است و آن آواز اول را که شنیده بودم که چون کرنا با من سخن می‌گفت، دیگرباره می‌گوید: «به اینجا صعود نما تا اموری را که بعد از این باید واقع شود به تو بنمایم.»"},{"v":2,"t":"فی الفور در روح شدم و دیدم که تختی درآسمان قائم است و بر آن تخت‌نشیننده‌ای."},{"v":3,"t":"وآن نشیننده، در صورت، مانند سنگ یشم و عقیق است و قوس قزحی در گرد تخت که به منظرشباهت به زمرد دارد"},{"v":4,"t":"و گرداگرد تخت، بیست وچهار تخت است؛ و بر آن تختها بیست و چهارپیر که جامه‌ای سفید در بر دارند نشسته دیدم و برسر ایشان تاجهای زرین."},{"v":5,"t":"و از تخت، برقها وصداها و رعدها برمی آید؛ و هفت چراغ آتشین پیش تخت افروخته که هفت روح خدا می‌باشند."},{"v":6,"t":"و در‌پیش تخت، دریایی از شیشه مانند بلور ودر میان تخت و گرداگرد تخت چهار حیوان که ازپیش و پس به چشمان پر هستند."},{"v":7,"t":"و حیوان اول مانند شیر بود؛ و حیوان دوم مانند گوساله؛ وحیوان سوم صورتی مانند انسان داشت؛ و حیوان چهارم مانند عقاب پرنده."},{"v":8,"t":"و آن چهار حیوان که هر یکی از آنها شش بال دارد، گرداگرد و درون به چشمان پر هستند وشبانه‌روز باز نمی ایستند از گفتن «قدوس قدوس قدوس، خداوند خدای قادر مطلق که بود وهست و می‌آید.»"},{"v":9,"t":"و چون آن حیوانات جلال وتکریم و سپاس به آن تخت‌نشینی که تا ابدالابادزنده است می‌خوانند،"},{"v":10,"t":"آنگاه آن بیست و چهار پیر می‌افتند در حضور آن تخت‌نشین و او را که تاابدالاباد زنده است عبادت می‌کنند و تاجهای خود را پیش تخت انداخته، می‌گویند:"},{"v":11,"t":"«ای خداوند، مستحقی که جلال و اکرام و قوت رابیابی، زیرا که تو همه موجودات را آفریده‌ای ومحض اراده تو بودند و آفریده شدند.»"}],"en":[{"v":1,"t":"After these things I looked and saw a door opened in heaven; and the first voice that I heard, like a trumpet speaking with me, was one saying, “Come up here, and I will show you the things which must happen after this.”"},{"v":2,"t":"Immediately I was in the Spirit. Behold, there was a throne set in heaven, and one sitting on the throne"},{"v":3,"t":"that looked like a jasper stone and a sardius. There was a rainbow around the throne, like an emerald to look at."},{"v":4,"t":"Around the throne were twenty-four thrones. On the thrones were twenty-four elders sitting, dressed in white garments, with crowns of gold on their heads."},{"v":5,"t":"Out of the throne proceed lightnings, sounds, and thunders. There were seven lamps of fire burning before his throne, which are the seven Spirits of God."},{"v":6,"t":"Before the throne was something like a sea of glass, similar to crystal. In the middle of the throne, and around the throne were four living creatures full of eyes before and behind."},{"v":7,"t":"The first creature was like a lion, the second creature like a calf, the third creature had a face like a man, and the fourth was like a flying eagle."},{"v":8,"t":"The four living creatures, each one of them having six wings, are full of eyes around and within. They have no rest day and night, saying, “Holy, holy, holy is the Lord God, the Almighty, who was and who is and who is to come!”"},{"v":9,"t":"When the living creatures give glory, honor, and thanks to him who sits on the throne, to him who lives forever and ever,"},{"v":10,"t":"the twenty-four elders fall down before him who sits on the throne and worship him who lives forever and ever, and throw their crowns before the throne, saying,"},{"v":11,"t":"“Worthy are you, our Lord and God, the Holy One, to receive the glory, the honor, and the power, for you created all things, and because of your desire they existed and were created!”"}],"hr":[{"v":1,"t":"Nakon toga vidjeh: gle, vrata otvorena na nebu! A onaj prijašnji glas, što ga ono začuh kao glas trublje što govoraše sa mnom, reče: “Uziđi ovamo i pokazat ću ti što se ima dogoditi nakon ovoga!”"},{"v":2,"t":"I odmah se u duhu zanijeh kad gle: prijestolje stajaše na nebu i na prijestolje Netko sjede."},{"v":3,"t":"Taj što sjede bijaše nalik na jaspis i sard. A uokolo prijestolja duga slična smaragdu."},{"v":4,"t":"Uokolo prijestolja dvadeset i četiri prijestolja, a na prijestolja sjedoše dvadeset i četiri starješine, obučene u bijele haljine, sa zlatnim vijencima na glavi."},{"v":5,"t":"Od prijestolja izlaze munje, i glasovi, i gromovi; pred prijestoljem gori sedam ognjenih zubalja, to jest sedam duhova Božjih,"},{"v":6,"t":"a pred prijestoljem kao neko stakleno more, nalik na prozirac. U sredini prijestolja, oko prijestolja, četiri bića, sprijeda i straga puna očiju:"},{"v":7,"t":"prvo biće slično lavu, drugo biće slično juncu, treće biće s licem kao čovječjim, četvrto biće slično letećem orlu."},{"v":8,"t":"Ta su četiri bića - u svakoga po šest krila - sve naokolo i iznutra puna očiju. Bez predaha dan i noć govore: “Svet! Svet! Svet Gospodin, Bog Svevladar, Onaj koji bijaše i koji jest i koji dolazi!”"},{"v":9,"t":"I kad god bića dadu slavu i čast pohvalnicu Onomu koji sjedi na prijestolju, Živomu u vijeke vjekova,"},{"v":10,"t":"dvadeset i četiri starješine padnu ničice pred Onim koji sjedi na prijestolju i poklone se njemu - Živomu u vijeke vjekova. I stavljaju svoje vijence pred prijestolje govoreći:"},{"v":11,"t":"“Dostojan si, Gospodine, Bože naš, primiti slavu i čast i moć! Jer ti si sve stvorio, i tvojom voljom sve postade i bi stvoreno!”"}]},"5":{"fa":[{"v":1,"t":"و دیدم بر دست راست تخت‌نشین، کتابی را که مکتوب است از درون و بیرون، ومختوم به هفت مهر."},{"v":2,"t":"و فرشته‌ای قوی را دیدم که به آواز بلند ندا می‌کند که «کیست مستحق اینکه کتاب را بگشاید و مهرهایش را بردارد؟»"},{"v":3,"t":"وهیچ‌کس در آسمان و در زمین و در زیرزمین نتوانست آن کتاب را باز کند یا بر آن نظر کند."},{"v":4,"t":"ومن بشدت می‌گریستم زیرا هیچ‌کس که شایسته گشودن کتاب یا خواندن آن یا نظر کردن بر آن باشد، یافت نشد."},{"v":5,"t":"و یکی از آن پیران به من می‌گوید: «گریان مباش! اینک آن شیری که ازسبط یهودا و ریشه داود است، غالب آمده است تاکتاب و هفت مهرش را بگشاید.»"},{"v":6,"t":"و دیدم در میان تخت و چهار حیوان و دروسط پیران، بره‌ای چون ذبح شده ایستاده است وهفت شاخ و هفت چشم دارد که هفت روح خدایند که به تمامی جهان فرستاده می‌شوند."},{"v":7,"t":"پس آمد و کتاب را از دست راست تخت‌نشین گرفته است."},{"v":8,"t":"و چون کتاب را گرفت، آن چهارحیوان و بیست و چهار پیر به حضور بره افتادند وهر یکی از ایشان بربطی و کاسه های زرین پر از بخور دارند که دعاهای مقدسین است."},{"v":9,"t":"وسرودی جدید می‌سرایند و می‌گویند: «مستحق گرفتن کتاب و گشودن مهرهایش هستی زیرا که ذبح شدی و مردمان را برای خدا به خون خود ازهر قبیله و زبان و قوم و امت خریدی"},{"v":10,"t":"و ایشان را برای خدای ما پادشاهان و کهنه ساختی و برزمین سلطنت خواهند کرد.»"},{"v":11,"t":"و دیدم و شنیدم صدای فرشتگان بسیار راکه گرداگرد تخت و حیوانات و پیران بودند و عددایشان کرورها کرور و هزاران هزار بود؛"},{"v":12,"t":"که به آواز بلند می‌گویند: «مستحق است بره ذبح شده که قوت و دولت و حکمت و توانایی و اکرام وجلال و برکت را بیابد.»"},{"v":13,"t":"و هر مخلوقی که در آسمان و بر زمین وزیرزمین و در دریاست و آنچه در آنها می‌باشد، شنیدم که می‌گویند: «تخت‌نشین و بره را برکت وتکریم و جلال و توانایی باد تا ابدالاباد.»"},{"v":14,"t":"وچهار حیوان گفتند: «آمین!» و آن پیران به روی درافتادند و سجده نمودند."}],"en":[{"v":1,"t":"I saw, in the right hand of him who sat on the throne, a book written inside and outside, sealed shut with seven seals."},{"v":2,"t":"I saw a mighty angel proclaiming with a loud voice, “Who is worthy to open the book, and to break its seals?”"},{"v":3,"t":"No one in heaven above, or on the earth, or under the earth, was able to open the book or to look in it."},{"v":4,"t":"Then I wept much, because no one was found worthy to open the book or to look in it."},{"v":5,"t":"One of the elders said to me, “Don’t weep. Behold, the Lion who is of the tribe of Judah, the Root of David, has overcome: he who opens the book and its seven seals.”"},{"v":6,"t":"I saw in the middle of the throne and of the four living creatures, and in the middle of the elders, a Lamb standing, as though it had been slain, having seven horns and seven eyes, which are the seven Spirits of God, sent out into all the earth."},{"v":7,"t":"Then he came, and he took it out of the right hand of him who sat on the throne."},{"v":8,"t":"Now when he had taken the book, the four living creatures and the twenty-four elders fell down before the Lamb, each one having a harp, and golden bowls full of incense, which are the prayers of the saints."},{"v":9,"t":"They sang a new song, saying, “You are worthy to take the book and to open its seals, for you were killed, and bought us for God with your blood out of every tribe, language, people, and nation,"},{"v":10,"t":"and made us kings and priests to our God; and we will reign on the earth.”"},{"v":11,"t":"I looked, and I heard something like a voice of many angels around the throne, the living creatures, and the elders. The number of them was ten thousands of ten thousands, and thousands of thousands,"},{"v":12,"t":"saying with a loud voice, “Worthy is the Lamb who has been killed to receive the power, wealth, wisdom, strength, honor, glory, and blessing!”"},{"v":13,"t":"I heard every created thing which is in heaven, on the earth, under the earth, on the sea, and everything in them, saying, “To him who sits on the throne and to the Lamb be the blessing, the honor, the glory, and the dominion, forever and ever! Amen!”"},{"v":14,"t":"The four living creatures said, “Amen!” Then the elders fell down and worshiped."}],"hr":[{"v":1,"t":"I vidjeh: na desnici Onoga koji sjedi na prijestolju - knjiga, iznutra i izvana ispisana, zapečaćena sa sedam pečata!"},{"v":2,"t":"I vidjeh snažna anđela gdje iza glasa proglašuje: “Tko je dostojan otvoriti knjigu i otpečatiti pečate njezine?”"},{"v":3,"t":"I nitko - ni na nebu, ni na zemlji, ni pod zemljom - nije mogao otvoriti knjige i pogledati u nju."},{"v":4,"t":"Briznem u plač jer se nitko ne nađe dostojan otvoriti knjigu i pogledati u nju."},{"v":5,"t":"A jedan od starješina reče: “Ne plači! Evo, pobijedi Lav iz plemena Judina, Korijen Davidov, on će otvoriti knjigu i sedam pečata njezinih."},{"v":6,"t":"I vidjeh: posred prijestolja i četiriju bića i posred starješina stoji, kao zaklan, Jaganjac sa sedam rogova i sedam očiju, to jest sedam duhova Božjih, po svoj zemlji poslanih."},{"v":7,"t":"On pristupi te iz desnice Onoga koji sjedi na prijestolju uzme knjigu."},{"v":8,"t":"A kad on uze knjigu, četiri bića i dvadeset i četiri starješine padoše ničice pred Jaganjca. U svakoga bijahu citre i zlatne posudice pune kada, to jest molitava svetačkih."},{"v":9,"t":"Pjevaju oni pjesmu novu: “Dostojan si uzeti knjigu i otvoriti pečate njezine jer si bio zaklan i otkupio, krvlju svojom, za Boga ljude iz svakoga plemena i jezika, puka i naroda;"},{"v":10,"t":"učinio si ih Bogu našemu kraljevstvom i svećenicima i kraljevat će na zemlji.”"},{"v":11,"t":"I vidjeh, i začuh glas anđela mnogih uokolo prijestolja, i bića i starješina. Bijaše ih na mirijade mirijada i tisuće tisuća."},{"v":12,"t":"Klicahu iza glasa: “Dostojan je zaklani Jaganjac primiti moć, i bogatstvo, i mudrost, i snagu, i čast, i slavu, i blagoslov!”"},{"v":13,"t":"I začujem: sve stvorenje, i na nebu, i na zemlji, i pod zemljom, i u moru - sve na njima i u njima govori: “Onomu koji sjedi na prijestolju i Jaganjcu blagoslov i čast, i slava i vlast u vijeke vjekova!”"},{"v":14,"t":"I četiri bića ponavljahu: “Amen!” A starješine padnu ničice i poklone se."}]},"6":{"fa":[{"v":1,"t":"و دیدم چون بره یکی از آن هفت مهر راگشود؛ و شنیدم یکی از آن چهار حیوان به صدایی مثل رعد می‌گوید: «بیا (و ببین )!»"},{"v":2,"t":"ودیدم که ناگاه اسبی سفید که سوارش کمانی داردو تاجی بدو داده شد و بیرون آمد، غلبه کننده و تاغلبه نماید."},{"v":3,"t":"و چون مهر دوم را گشود، حیوان دوم راشنیدم که می‌گوید: «بیا (و ببین )!»"},{"v":4,"t":"و اسبی دیگر، آتشگون بیرون آمد و سوارش را توانایی داده شده بود که سلامتی را از زمین بردارد و تا یکدیگررا بکشند؛ و به وی شمشیری بزرگ داده شد."},{"v":5,"t":"و چون مهر سوم را گشود، حیوان سوم راشنیدم که می‌گوید: «بیا (و ببین )!» و دیدم اینک اسبی سیاه که سوارش ترازویی بدست خود دارد."},{"v":6,"t":"و از میان چهار حیوان، آوازی را شنیدم که می‌گوید: «یک هشت یک گندم به یک دینار و سه هشت یک جو به یک دینار و به روغن و شراب ضرر مرسان.»"},{"v":7,"t":"و چون مهر‌چهارم را گشود، حیوان چهارم را شنیدم که می‌گوید: «بیا (و ببین )!»"},{"v":8,"t":"و دیدم که اینک اسبی زرد و کسی بر آن سوار شده که اسم اوموت است و عالم اموات از عقب او می‌آید؛ و به آن دو اختیار بر یک ربع زمین داده شد تا به شمشیر و قحط و موت و با وحوش زمین بکشند."},{"v":9,"t":"و چون مهر پنجم را گشود، در زیر مذبح دیدم نفوس آنانی را که برای کلام خدا و شهادتی که داشتند کشته شده بودند؛"},{"v":10,"t":"که به آواز بلندصدا کرده، می‌گفتند: «ای خداوند قدوس و حق، تا به کی انصاف نمی نمایی و انتقام خون ما را ازساکنان زمین نمی کشی؟»"},{"v":11,"t":"و به هر یکی از ایشان جامه‌ای سفید داده شد و به ایشان گفته شد که اندکی دیگر آرامی نمایند تا عدد همقطاران که مثل ایشان کشته خواهند شد، تمام شود."},{"v":12,"t":"و چون مهر ششم را گشود، دیدم که زلزله‌ای عظیم واقع شد و آفتاب چون پلاس پشمی سیاه گردید و تمام ماه چون خون گشت؛"},{"v":13,"t":"و ستارگان آسمان بر زمین فرو ریختند، مانند درخت انجیری که از باد سخت به حرکت آمده، میوه های نارس خود را می‌افشاند."},{"v":14,"t":"و آسمان چون طوماری پیچیده شده، از جا برده شد و هرکوه و جزیره از مکان خود منتقل گشت."},{"v":15,"t":"وپادشاهان زمین و بزرگان و سپه سالاران ودولتمندان و جباران و هر غلام و آزاد خود را درمغاره‌ها و صخره های کوهها پنهان کردند."},{"v":16,"t":"و به کوهها و صخره‌ها می‌گویند که «بر ما بیفتید و ما رامخفی سازید از روی آن تخت‌نشین و از غضب بره؛"},{"v":17,"t":"زیرا روز عظیم غضب او رسیده است وکیست که می‌تواند ایستاد؟»"}],"en":[{"v":1,"t":"I saw that the Lamb opened one of the seven seals, and I heard one of the four living creatures saying, as with a voice of thunder, “Come and see!”"},{"v":2,"t":"Then a white horse appeared, and he who sat on it had a bow. A crown was given to him, and he came out conquering, and to conquer."},{"v":3,"t":"When he opened the second seal, I heard the second living creature saying, “Come!”"},{"v":4,"t":"Another came out, a red horse. To him who sat on it was given power to take peace from the earth, and that they should kill one another. There was given to him a great sword."},{"v":5,"t":"When he opened the third seal, I heard the third living creature saying, “Come and see!” And behold, a black horse, and he who sat on it had a balance in his hand."},{"v":6,"t":"I heard a voice in the middle of the four living creatures saying, “A choenix of wheat for a denarius, and three choenix of barley for a denarius! Don’t damage the oil and the wine!”"},{"v":7,"t":"When he opened the fourth seal, I heard the fourth living creature saying, “Come and see!”"},{"v":8,"t":"And behold, a pale horse, and the name of he who sat on it was Death. Hades followed with him. Authority over one fourth of the earth, to kill with the sword, with famine, with death, and by the wild animals of the earth was given to him."},{"v":9,"t":"When he opened the fifth seal, I saw underneath the altar the souls of those who had been killed for the Word of God, and for the testimony of the Lamb which they had."},{"v":10,"t":"They cried with a loud voice, saying, “How long, Master, the holy and true, until you judge and avenge our blood on those who dwell on the earth?”"},{"v":11,"t":"A long white robe was given to each of them. They were told that they should rest yet for a while, until their fellow servants and their brothers, who would also be killed even as they were, should complete their course."},{"v":12,"t":"I saw when he opened the sixth seal, and there was a great earthquake. The sun became black as sackcloth made of hair, and the whole moon became as blood."},{"v":13,"t":"The stars of the sky fell to the earth, like a fig tree dropping its unripe figs when it is shaken by a great wind."},{"v":14,"t":"The sky was removed like a scroll when it is rolled up. Every mountain and island was moved out of its place."},{"v":15,"t":"The kings of the earth, the princes, the commanding officers, the rich, the strong, and every slave and free person, hid themselves in the caves and in the rocks of the mountains."},{"v":16,"t":"They told the mountains and the rocks, “Fall on us, and hide us from the face of him who sits on the throne, and from the wrath of the Lamb,"},{"v":17,"t":"for the great day of his wrath has come, and who is able to stand?”"}],"hr":[{"v":1,"t":"I vidjeh: kad Jaganjac otvori prvi od sedam pečata, začujem gdje prvo od četiri bića govori glasom kao gromovnim: “Dođi!”"},{"v":2,"t":"Pogledam, a ono konj bijelac i u njegova konjanika luk. I dan mu je vijenac te kao pobjednik pođe da pobijedi."},{"v":3,"t":"Kad Jaganjac otvori drugi pečat, začujem drugo biće gdje govori: “Dođi!”"},{"v":4,"t":"I iziđe drugi konj, riđan. I njegovu je konjaniku dano dignuti mir sa zemlje da se ljudi među sobom pokolju. I dan mu je mač velik."},{"v":5,"t":"Kad Jaganjac otvori treći pečat, začujem treće biće gdje govori: “Dođi!” Pogledam, a ono konj vranac i njegovu konjaniku u ruci tezulja."},{"v":6,"t":"Tada začujem kao neki glas isred četiriju bića gdje govori: “Mjera pšenice za denar! Tri mjere ječma za denar! A ulju i vinu ne udi!”"},{"v":7,"t":"Kad Jaganjac otvori četvrti pečat, začujem glas četvrtoga bića gdje govori: “Dođi!”"},{"v":8,"t":"Pogledam, a ono konj sivac; konjaniku njegovu ime je “Smrt” i prati ga Podzemlje. Dana im je vlast nad četvrtinom zemlje: ubijati mačem i glađu i smrću i zvijerima zemaljskim."},{"v":9,"t":"Kad Jaganjac otvori peti pečat, vidjeh pod žrtvenikom duše zaklanih zbog riječi Božje i zbog svjedočanstva što ga imahu."},{"v":10,"t":"Vikahu iza glasa: “Ta dokle, Gospodaru sveti i istiniti! Zar nećeš suditi i osvetiti krv našu na pozemljarima?”"},{"v":11,"t":"I svakome je od njih dana bijela haljina i rečeno im je neka se strpe još malo vremena dok se ne ispuni broj njihovih sudrugova u službi i braće njihove koja imaju biti pobijena kao i oni."},{"v":12,"t":"I vidjeh: kad Jaganjac otvori šesti pečat, potres velik nasta. I sunce pocrnje kao dlakava kostrijet, sav mjesec posta kao krv."},{"v":13,"t":"I zvijezde padoše s neba na zemlju kao što smokva smokvice stresa kad je potrese žestok vjetar."},{"v":14,"t":"Nebo iščeznu kao savijena knjiga, a sve se planine i otoci pokrenuše s mjesta."},{"v":15,"t":"Kraljevi zemaljski, i velikaši, i vojvode, i bogataši, i mogućnici, rob i slobodnjak - svi se sakriše u spilje i pećine gorske"},{"v":16,"t":"govoreći gorama i pećinama: “Padnite na nas i sakrijte nas od lica Onoga koji sjedi na prijestolju i od srdžbe Jaganjčeve."},{"v":17,"t":"Jer dođe Dan onaj veliki srdžbe njihove i tko će opstati!”"}]},"7":{"fa":[{"v":1,"t":"و بعد از آن دیدم چهار فرشته، بر چهارگوشه زمین ایستاده، چهار باد زمین را بازمی دارند تا باد بر زمین و بر دریا و بر هیچ درخت نوزد."},{"v":2,"t":"و فرشته دیگری دیدم که از مطلع آفتاب بالا می‌آید و مهر خدای زنده را دارد. و به آن چهار فرشته‌ای که بدیشان داده شد که زمین ودریا را ضرر رسانند، به آواز بلند ندا کرده،"},{"v":3,"t":"می گوید: «هیچ ضرری به زمین و دریا و درختان مرسانید تا بندگان خدای خود را بر پیشانی‌ایشان مهر زنیم."},{"v":4,"t":"و عدد مهرشدگان را شنیدم که ازجمیع اسباط بنی‌اسرائیل، صد و چهل و چهارهزار مهر شدند."},{"v":5,"t":"و از سبط یهودا دوازده هزار مهر شدند؛ و ازسبط روبین دوازده هزار؛ و از سبط جاد دوازده هزار؛"},{"v":6,"t":"و از سبط اشیر دوازده هزار؛ و از سبطنفتالیم دوازده هزار؛ و از سبط منسی دوازده هزار؛"},{"v":7,"t":"و از سبط شمعون دوازده هزار؛ و از سبط لاوی دوازده هزار؛ و از سبط یساکار دوازده هزار؛"},{"v":8,"t":"ازسبط زبولون دوازده هزار؛ و از سبط یوسف دوازده هزار؛ و از سبط بنیامین دوازده هزار مهرشدند."},{"v":9,"t":"و بعد از این دیدم که اینک گروهی عظیم که هیچ‌کس ایشان را نتواند شمرد، از هر امت و قبیله و قوم و زبان در‌پیش تخت و در حضور بره به‌جامه های سفید آراسته و شاخه های نخل به‌دست گرفته، ایستاده‌اند"},{"v":10,"t":"و به آواز بلند نداکرده، می‌گویند: «نجات، خدای ما را که بر تخت نشسته است و بره را است.»"},{"v":11,"t":"و جمیع فرشتگان در گرد تخت و پیران و چهار حیوان ایستاده بودند. و در‌پیش تخت به روی درافتاده، خدا راسجده کردند"},{"v":12,"t":"و گفتند: «آمین! برکت و جلال وحکمت و سپاس و اکرام و قوت و توانایی، خدای ما را باد تا ابدالاباد. آمین.»"},{"v":13,"t":"و یکی از پیران متوجه شده، به من گفت: «این سفیدپوشان کیانند و از کجا آمده‌اند؟»"},{"v":14,"t":"من او را گفتم: «خداوندا تو می‌دانی!» مرا گفت: «ایشان کسانی می‌باشند که از عذاب سخت بیرون می‌آیند و لباس خود را به خون بره شست وشوکرده، سفید نموده‌اند."},{"v":15,"t":"از این جهت پیش روی تخت خدایند و شبانه‌روز در هیکل او وی راخدمت می‌کنند و آن تخت‌نشین، خیمه خود را برایشان برپا خواهد داشت."},{"v":16,"t":"و دیگر هرگز گرسنه و تشنه نخواهند شد و آفتاب و هیچ گرما بر ایشان نخواهد رسید."},{"v":17,"t":"زیرا بره‌ای که در میان تخت است، شبان ایشان خواهد بود و به چشمه های آب حیات، ایشان را راهنمایی خواهد نمود؛ وخدا هر اشکی را از چشمان ایشان پاک خواهدکرد.»"}],"en":[{"v":1,"t":"After this, I saw four angels standing at the four corners of the earth, holding the four winds of the earth, so that no wind would blow on the earth, or on the sea, or on any tree."},{"v":2,"t":"I saw another angel ascend from the sunrise, having the seal of the living God. He cried with a loud voice to the four angels to whom it was given to harm the earth and the sea,"},{"v":3,"t":"saying, “Don’t harm the earth, the sea, or the trees, until we have sealed the bondservants of our God on their foreheads!”"},{"v":4,"t":"I heard the number of those who were sealed, one hundred forty-four thousand, sealed out of every tribe of the children of Israel:"},{"v":5,"t":"of the tribe of Judah twelve thousand were sealed, of the tribe of Reuben twelve thousand, of the tribe of Gad twelve thousand,"},{"v":6,"t":"of the tribe of Asher twelve thousand, of the tribe of Naphtali twelve thousand, of the tribe of Manasseh twelve thousand,"},{"v":7,"t":"of the tribe of Simeon twelve thousand, of the tribe of Levi twelve thousand, of the tribe of Issachar twelve thousand,"},{"v":8,"t":"of the tribe of Zebulun twelve thousand, of the tribe of Joseph twelve thousand, and of the tribe of Benjamin twelve thousand were sealed."},{"v":9,"t":"After these things I looked, and behold, a great multitude which no man could count, out of every nation and of all tribes, peoples, and languages, standing before the throne and before the Lamb, dressed in white robes, with palm branches in their hands."},{"v":10,"t":"They cried with a loud voice, saying, “Salvation be to our God, who sits on the throne, and to the Lamb!”"},{"v":11,"t":"All the angels were standing around the throne, the elders, and the four living creatures; and they fell on their faces before his throne, and worshiped God,"},{"v":12,"t":"saying, “Amen! Blessing, glory, wisdom, thanksgiving, honor, power, and might, be to our God forever and ever! Amen.”"},{"v":13,"t":"One of the elders answered, saying to me, “These who are arrayed in the white robes, who are they, and where did they come from?”"},{"v":14,"t":"I told him, “My lord, you know.” He said to me, “These are those who came out of the great suffering. They washed their robes and made them white in the Lamb’s blood."},{"v":15,"t":"Therefore they are before the throne of God, and they serve him day and night in his temple. He who sits on the throne will spread his tabernacle over them."},{"v":16,"t":"They will never be hungry or thirsty any more. The sun won’t beat on them, nor any heat;"},{"v":17,"t":"for the Lamb who is in the middle of the throne shepherds them and leads them to springs of life-giving waters. And God will wipe away every tear from their eyes.”"}],"hr":[{"v":1,"t":"Nakon toga vidjeh: četiri anđela stoje na četiri kraja zemlje zadržavajući četiri vjetra zemaljska da nikakav vjetar ne puše ni zemljom ni morem nit ikojim drvećem."},{"v":2,"t":"I vidjeh drugoga jednog anđela gdje uzlazi od istoka sunčeva s pečatom Boga živoga. On povika iza glasa onoj četvorici anđela kojima bi dano nauditi zemlji i moru:"},{"v":3,"t":"“Ne udite ni zemlji ni moru ni drveću dok ne opečatimo sluge Boga našega na čelima!”"},{"v":4,"t":"I začujem broj opečaćenih - sto četrdeset i četiri tisuće opečaćenih iz svih plemena sinova Izraelovih:"},{"v":5,"t":"iz plemena Judina dvanaest tisuća opečaćenih, iz plemena Rubenova dvanaest tisuća, iz plemena Gadova dvanaest tisuća,"},{"v":6,"t":"iz plemena Ašerova dvanaest tisuća, iz plemena Naftalijeva dvanest tisuća, iz plemena Manašeova dvanaest tisuća,"},{"v":7,"t":"iz plemena Šimunova dvanaest tisuća, iz plemena Levijeva dvanaest tisuća, iz plemena Jisakarova dvanaest tisuća,"},{"v":8,"t":"iz plemena Zebulunova dvanaest tisuća, iz plemena Josipova dvanaest tisuća, iz plemena Benjaminova dvanaest tisuća opečaćenih."},{"v":9,"t":"Nakon toga vidjeh: eno velikoga mnoštva, što ga nitko ne mogaše izbrojiti, iz svakoga naroda, i plemena, i puka, i jezika! Stoje pred prijestoljem i pred Jaganjcem odjeveni u bijele haljine; palme im u rukama."},{"v":10,"t":"Viču iz glasa: “Spasenje Bogu našemu koji sjedi na prijestolju i Jaganjcu!”"},{"v":11,"t":"I svi anđeli, što stajahu uokolo prijestolja i starješina i četiriju bića, padoše pred prijestoljem ničice, na svoja lica,"},{"v":12,"t":"i pokloniše se Bogu govoreći: “Amen! Blagoslov i slava, i mudrost, i zahvalnica, i čast, i moć i snaga Bogu našemu u vijeke vjekova. Amen.”"},{"v":13,"t":"I jedan me od starješina upita: “Ovi odjeveni u bijele haljine, tko su i odakle dođoše?”"},{"v":14,"t":"Odgovorih mu: “Gospodine moj, ti to znaš.” A on će mi: “Oni dođoše iz nevolje velike i oprali su haljine svoje i ubijelili ih u krvi Jaganjčevoj."},{"v":15,"t":"Zato su pred prijestoljem Božjim i služe mu dan i noć u hramu njegovu, i Onaj koji sjedi na prijestolju razapet će Šator svoj nad njima."},{"v":16,"t":"Neće više gladovati ni žeđati, neće ih više paliti sunce nit ikakva žega"},{"v":17,"t":"jer - Jaganjac koji je posred prijestolja bit će pastir njihov i vodit će ih na izvore voda života. I otrt će Bog svaku suzu s očiju njihovih.”"}]},"8":{"fa":[{"v":1,"t":"و چون مهر هفتم را گشود، خاموشی قریب به نیم ساعت در آسمان واقع شد."},{"v":2,"t":"و دیدم هفت فرشته را که در حضور خد ایستاده‌اند که به ایشان هفت کرنا داده شد."},{"v":3,"t":"و فرشته‌ای دیگرآمده، نزد مذبح بایستاد با مجمری طلا و بخوربسیار بدو داده شد تا آن را به دعاهای جمیع مقدسین، بر مذبح طلا که پیش تخت است بدهد،"},{"v":4,"t":"و دود بخور، از دست فرشته با دعاهای مقدسین در حضور خدا بالا رفت."},{"v":5,"t":"پس آن فرشته مجمررا گرفته، از آتش مذبح آن را پر کرد و به سوی زمین انداخت و صداها و رعدها و برقها و زلزله حادث گردید."},{"v":6,"t":"و هفت فرشته‌ای که هفت کرنا را داشتندخود را مستعد نواختن نمودند"},{"v":7,"t":"و چون اولی بنواخت تگرگ و آتش با خون آمیخته شده، واقع گردید و به سوی زمین ریخته شد و ثلث درختان سوخته و هر گیاه سبز سوخته شد."},{"v":8,"t":"و فرشته دوم بنواخت که ناگاه مثال کوهی بزرگ، به آتش افروخته شده، به دریا افکنده شد و ثلث دریا خون گردید،"},{"v":9,"t":"و ثلث مخلوقات دریایی که جان داشتند، بمردند و ثلث کشتیها تباه گردید."},{"v":10,"t":"و چون فرشته سوم نواخت، ناگاه ستاره‌ای عظیم، چون چراغی افروخته شده از آسمان فرود آمد و بر ثلث نهرها و چشمه های آب افتاد."},{"v":11,"t":"و اسم آن ستاره را افسنتین می‌خوانند؛ و ثلث آبها به افسنتین مبدل گشت و مردمان بسیار ازآبهایی که تلخ شده بود مردند."},{"v":12,"t":"و فرشته چهارم بنواخت و به ثلث آفتاب وثلث ماه و ثلث ستارگان صدمه رسید تا ثلث آنهاتاریک گردید و ثلث روز و ثلث شب همچنین بی‌نور شد."},{"v":13,"t":"و عقابی را دیدم و شنیدم که دروسط آسمان می‌پرد و به آواز بلند می‌گوید: «وای وای وای بر ساکنان زمین، بسبب صداهای دیگرکرنای آن سه فرشته‌ای که می‌باید بنوازند.»"}],"en":[{"v":1,"t":"When he opened the seventh seal, there was silence in heaven for about half an hour."},{"v":2,"t":"I saw the seven angels who stand before God, and seven trumpets were given to them."},{"v":3,"t":"Another angel came and stood over the altar, having a golden censer. Much incense was given to him, that he should add it to the prayers of all the saints on the golden altar which was before the throne."},{"v":4,"t":"The smoke of the incense, with the prayers of the saints, went up before God out of the angel’s hand."},{"v":5,"t":"The angel took the censer, and he filled it with the fire of the altar, then threw it on the earth. Thunders, sounds, lightnings, and an earthquake followed."},{"v":6,"t":"The seven angels who had the seven trumpets prepared themselves to sound."},{"v":7,"t":"The first sounded, and there followed hail and fire, mixed with blood, and they were thrown to the earth. One third of the earth was burned up, and one third of the trees were burned up, and all green grass was burned up."},{"v":8,"t":"The second angel sounded, and something like a great burning mountain was thrown into the sea. One third of the sea became blood,"},{"v":9,"t":"and one third of the living creatures which were in the sea died. One third of the ships were destroyed."},{"v":10,"t":"The third angel sounded, and a great star fell from the sky, burning like a torch, and it fell on one third of the rivers, and on the springs of water."},{"v":11,"t":"The name of the star is “Wormwood.” One third of the waters became wormwood. Many people died from the waters, because they were made bitter."},{"v":12,"t":"The fourth angel sounded, and one third of the sun was struck, and one third of the moon, and one third of the stars, so that one third of them would be darkened; and the day wouldn’t shine for one third of it, and the night in the same way."},{"v":13,"t":"I saw, and I heard an eagle, flying in mid heaven, saying with a loud voice, “Woe! Woe! Woe to those who dwell on the earth, because of the other blasts of the trumpets of the three angels, who are yet to sound!”"}],"hr":[{"v":1,"t":"Kad Jaganjac otvori sedmi pečat, nasta muk na nebu oko pola sata."},{"v":2,"t":"I vidjeh: sedmorici anđela što stoje pred Bogom dano je sedam trubalja."},{"v":3,"t":"I drugi jedan anđeo pristupi i sa zlatnom kadionicom stane na žrtvenik. I dano mu je mnogo kada da ga s molitvama svih svetih prinese na zlatni žrtvenik pred prijestoljem."},{"v":4,"t":"I vinu se dim kadni s molitvama svetih iz ruke anđelove pred lice Božje."},{"v":5,"t":"Anđeo uze kadionicu, napuni je vatrom sa žrtvenika i prosu na zemlju. I udariše gromovi, i glasovi, i munje, i potres."},{"v":6,"t":"A sedam anđela sa sedam trubalja pripremiše se da zatrube."},{"v":7,"t":"Prvi zatrubi. I nastadoše tuča i oganj, pomiješani s krvlju, i budu bačeni na zemlju. I trećina zemlje izgorje, i trećina stabala izgorje, i sva zelena trava izgorje."},{"v":8,"t":"Drugi anđeo zatrubi. I nešto kao gora velika, ognjem zapaljena, bačeno bi u more. I trećina se mora pretvori u krv"},{"v":9,"t":"te izginu trećina stvorenja što u moru žive i trećina lađa propade."},{"v":10,"t":"Treći anđeo zatrubi. I pade s neba zvijezda velika - gorjela je kao zublja - pade na trećinu rijeka i na izvore voda."},{"v":11,"t":"Zvijezdi je ime Pelin. I trećina se voda pretvori u pelin te mnoštvo ljudi poginu od zagorčenih voda."},{"v":12,"t":"Četvrti anđeo zatrubi. I bi udarena trećina sunca i trećina mjeseca i trećina zvijezda te pomrčaše za trećinu. I dan izgubi trećinu svoga sjaja, a tako i noć."},{"v":13,"t":"I vidjeh i začuh orla: letio posred neba i vikao iza glasa: “Jao! Jao! Jao pozemljarima od novih glasova trubalja preostale trojice anđela koji će sad-na zatrubiti!”"}]},"9":{"fa":[{"v":1,"t":"و چون فرشته پنجم نواخت، ستاره‌ای رادیدم که بر زمین افتاده بود و کلید چاه هاویه بدو داده شد."},{"v":2,"t":"و چاه هاویه را گشاد ودودی چون دود تنوری عظیم از چاه بالا آمد وآفتاب و هوا از دود چاه تاریک گشت."},{"v":3,"t":"و از میان دود، ملخها به زمین برآمدند و به آنها قوتی چون قوت عقربهای زمین داده شد"},{"v":4,"t":"و بدیشان گفته شدکه ضرر نرسانند نه به گیاه زمین و نه به هیچ سبزی و نه به درختی بلکه به آن مردمانی که مهر خدا رابر پیشانی خود ندارند."},{"v":5,"t":"و به آنها داده شد که ایشان را نکشند بلکه تا مدت پنج ماه معذب بدارند و اذیت آنها مثل اذیت عقرب بود، وقتی که کسی را نیش زند."},{"v":6,"t":"و در آن ایام، مردم طلب موت خواهند کرد و آن را نخواهند یافت و تمنای موت خواهند داشت، اما موت از ایشان خواهدگریخت."},{"v":7,"t":"و صورت ملخها چون اسبهای آراسته شده برای جنگ بود و بر سر ایشان مثل تاجهای شبیه طلا، و چهره های ایشان شبیه صورت انسان بود."},{"v":8,"t":"و مویی داشتند چون موی زنان، و دندانهایشان مانند دندانهای شیران بود."},{"v":9,"t":"و جوشنها داشتند، چون جوشنهای آهنین و صدای بالهای ایشان، مثل صدای ارابه های اسبهای بسیار که به جنگ همی تازند."},{"v":10,"t":"و دمها چون عقربها با نیشهاداشتند؛ و در دم آنها قدرت بود که تا مدت پنج ماه مردم را اذیت نمایند."},{"v":11,"t":"و بر خود، پادشاهی داشتند که ملک الهاویه است که در عبرانی به ابدون مسمی است و در یونانی او را اپلیون خوانند."},{"v":12,"t":"یک وای گذشته است. اینک دو وای دیگر بعد از این می‌آید."},{"v":13,"t":"و فرشته ششم بنواخت که ناگاه آوازی از میان چهار شاخ مذبح طلایی که در حضور خداست شنیدم"},{"v":14,"t":"که به آن فرشته ششم که صاحب کرنابود می‌گوید: «آن چهار فرشته را که بر نهر عظیم فرات بسته‌اند، خلاص کن.»"},{"v":15,"t":"پس آن چهارفرشته که برای ساعت و روز و ماه و سال معین مهیا شده‌اند تا اینکه ثلث مردم را بکشند، خلاصی یافتند."},{"v":16,"t":"و عدد جنود سواران، دویست هزار هزار بود که عدد ایشان را شنیدم."},{"v":17,"t":"و به اینطور اسبان و سواران ایشان را دررویا دیدم که جوشنهای آتشین و آسمانجونی وکبریتی دارند و سرهای اسبان چون سر شیران است و از دهانشان آتش و دود و کبریت بیرون می‌آید."},{"v":18,"t":"از این سه بلا یعنی آتش و دود وکبریت که از دهانشان برمی آید، ثلث مردم هلاک شدند."},{"v":19,"t":"زیرا که قدرت اسبان در دهان و دم ایشان است، زیرا که دمهای آنها چون مارهاست که سرها دارد و به آنها اذیت می‌کنند."},{"v":20,"t":"و سایرمردم که به این بلایا کشته نگشتند، از اعمال دستهای خود توبه نکردند تا آنکه عبادت دیوها وبتهای طلا و نقره و برنج و سنگ و چوب را که طاقت دیدن و شنیدن و خرامیدن ندارند، ترک کنند؛"},{"v":21,"t":"و از قتل‌ها و جادوگریها و زنا و دزدیهای خود توبه نکردند."}],"en":[{"v":1,"t":"The fifth angel sounded, and I saw a star from the sky which had fallen to the earth. The key to the pit of the abyss was given to him."},{"v":2,"t":"He opened the pit of the abyss, and smoke went up out of the pit, like the smoke from a burning furnace. The sun and the air were darkened because of the smoke from the pit."},{"v":3,"t":"Then out of the smoke came locusts on the earth, and power was given to them, as the scorpions of the earth have power."},{"v":4,"t":"They were told that they should not hurt the grass of the earth, neither any green thing, neither any tree, but only those people who don’t have God’s seal on their foreheads."},{"v":5,"t":"They were given power, not to kill them, but to torment them for five months. Their torment was like the torment of a scorpion when it strikes a person."},{"v":6,"t":"In those days people will seek death, and will in no way find it. They will desire to die, and death will flee from them."},{"v":7,"t":"The shapes of the locusts were like horses prepared for war. On their heads were something like golden crowns, and their faces were like people’s faces."},{"v":8,"t":"They had hair like women’s hair, and their teeth were like those of lions."},{"v":9,"t":"They had breastplates like breastplates of iron. The sound of their wings was like the sound of many chariots and horses rushing to war."},{"v":10,"t":"They have tails like those of scorpions, with stingers. In their tails they have power to harm men for five months."},{"v":11,"t":"They have over them as king the angel of the abyss. His name in Hebrew is “Abaddon”, but in Greek, he has the name “Apollyon”."},{"v":12,"t":"The first woe is past. Behold, there are still two woes coming after this."},{"v":13,"t":"The sixth angel sounded. I heard a voice from the horns of the golden altar which is before God,"},{"v":14,"t":"saying to the sixth angel who had the trumpet, “Free the four angels who are bound at the great river Euphrates!”"},{"v":15,"t":"The four angels were freed who had been prepared for that hour and day and month and year, so that they might kill one third of mankind."},{"v":16,"t":"The number of the armies of the horsemen was two hundred million. I heard the number of them."},{"v":17,"t":"Thus I saw the horses in the vision and those who sat on them, having breastplates of fiery red, hyacinth blue, and sulfur yellow; and the horses’ heads resembled lions’ heads. Out of their mouths proceed fire, smoke, and sulfur."},{"v":18,"t":"By these three plagues, one third of mankind was killed: by the fire, the smoke, and the sulfur, which proceeded out of their mouths."},{"v":19,"t":"For the power of the horses is in their mouths and in their tails. For their tails are like serpents, and have heads; and with them they harm."},{"v":20,"t":"The rest of mankind, who were not killed with these plagues, didn’t repent of the works of their hands, that they wouldn’t worship demons, and the idols of gold, and of silver, and of brass, and of stone, and of wood, which can’t see, hear, or walk."},{"v":21,"t":"They didn’t repent of their murders, their sorceries, their sexual immorality, or their thefts."}],"hr":[{"v":1,"t":"Peti anđeo zatrubi. I vidjeh: zvijezda je s neba na zemlju pala i dani su joj ključi zjala Bezdanova."},{"v":2,"t":"Ona otvori zjalo Bezdanovo i vinu se iz zjala dim kao dim iz peći goleme te pomrča sunce i zrak od dima iz zjala."},{"v":3,"t":"Iz dima pak iziđoše na zemlju skakavci i dana im je moć kakvu imaju štipavci zemaljski."},{"v":4,"t":"I zapovjeđeno im je da ne ude travi zemaljskoj nit ikojem zelenilu nit ikojem stablu, nego samo ljudima koji nemaju pečata Božjega na čelu."},{"v":5,"t":"I dano im je ne da ih ubijaju, nego samo da ih muče pet mjeseci, a muka njihova da bude kao muka od uboda štipavaca."},{"v":6,"t":"U one će dane ljudi iskati smrt, ali je neće naći; poželjet će umrijeti, ali smrt će bježati od njih."},{"v":7,"t":"Skakavci bijahu izgledom nalik na konje za boj spremne. Na glavama im kao neki zlatni vijenci, lica im kao u ljudi,"},{"v":8,"t":"kose kao u žena, a zubi kao u lavova."},{"v":9,"t":"Imahu oklope kao od željeza, a šum krila njihovih kao štropot bojnih kola s mnogo konja što u boj jure."},{"v":10,"t":"Repovi im kao u štipavaca, sa žalcima, a u repovima im moć da ude ljudima pet mjeseci."},{"v":11,"t":"Nad njima je kralj, anđeo Bezdana, hebrejski mu ime Abadon, grčki Apolion - Upropastitelj."},{"v":12,"t":"Prvi Jao prođe. Evo, za njim dolaze još dva druga Jao."},{"v":13,"t":"Šesti anđeo zatrubi. I začujem neki glas iz rogova zlatnoga žrtvenika pred Bogom."},{"v":14,"t":"Govoraše šestom anđelu koji je držao trublju: “Odriješi ona četiri anđela svezana na Rijeci velikoj, Eufratu.”"},{"v":15,"t":"I odriješena bijahu četiri anđela, spremna za taj čas i dan i mjesec i godinu, da pobiju trećinu ljudi."},{"v":16,"t":"A broj četa konjaničkih, kako sam čuo, bijaše dvije mirijade mirijada."},{"v":17,"t":"Ovako u viđenju vidjeh konje i njihove jahače: imahu oklope ognjene, plavetne i sumporne boje; glave im kao u lavova, iz usta im sukljao oganj, dim i sumpor."},{"v":18,"t":"Od ovih triju zala poginu trećina ljudi - od ognja, dima i sumpora što sukljahu konjima iz usta."},{"v":19,"t":"Doista, snaga je ovim konjima u ustima i repovima: repovi im kao u zmija, s glavama kojima ude."},{"v":20,"t":"Ipak, preostali ljudi, što ne poginuše od tih zala, ne obratiše se od djela ruku svojih, da se više ne klanjaju zlodusima i kumirima - ni zlatnima, ni srebrnima, ni mjedenima, ni kamenima ni drvenima koji niti vide niti čuju nit hodaju -"},{"v":21,"t":"i ne obratiše se od svojih ubojstava ni od svojih čaranja ni od svoga bluda niti od svojih krađa."}]},"10":{"fa":[{"v":1,"t":"و دیدم فرشته زورآور دیگری را که ازآسمان نازل می‌شود که ابری دربر دارد، و قوس قزحی بر سرش و چهره‌اش مثل آفتاب وپایهایش مثل ستونهای آتش."},{"v":2,"t":"و در دست خودکتابچه‌ای گشوده دارد و پای راست خود را بردریا و پای چپ خود را بر زمین نهاد؛"},{"v":3,"t":"و به آوازبلند، چون غرش شیر صدا کرد؛ و چون صدا کرد، هفت رعد به صداهای خود سخن‌گفتند."},{"v":4,"t":"و چون هفت رعد سخن‌گفتند، حاضر شدم که بنویسم. آنگاه آوازی از آسمان شنیدم که می‌گوید: «آنچه هفت رعد گفتند مهر کن و آنها را منویس.»"},{"v":5,"t":"و آن فرشته‌ای را که بر دریا و زمین ایستاده دیدم، دست راست خود را به سوی آسمان بلندکرده،"},{"v":6,"t":"قسم خورد به او که تا ابدالاباد زنده است که آسمان و آنچه را که در آن است و زمین و آنچه را که در آن است و دریا و آنچه را که در آن است آفرید که «بعد از این زمانی نخواهد بود،"},{"v":7,"t":"بلکه درایام صدای فرشته هفتم، چون کرنا را می‌بایدبنوازد، سر خدا به اتمام خواهد رسید، چنانکه بندگان خود انبیا را بشارت داد.»"},{"v":8,"t":"و آن آوازی که از آسمان شنیده بودم، باردیگر شنیدم که مرا خطاب کرده، می‌گوید: «برو وکتابچه گشاده را از دست فرشته‌ای که بر دریا وزمین ایستاده است بگیر.»"},{"v":9,"t":"پس به نزد فرشته رفته، به وی گفتم که کتابچه را به من بدهد. او مرا گفت: «بگیر و بخور که اندرونت را تلخ خواهد نمود، لکن در دهانت چون عسل شیرین خواهد بود.»"},{"v":10,"t":"پس کتابچه رااز دست فرشته گرفته، خوردم که در دهانم مثل عسل شیرین بود، ولی چون خورده بودم، درونم تلخ گردید."},{"v":11,"t":"و مرا گفت که «می‌باید تو اقوام وامت‌ها و زبانها و پادشاهان بسیار را نبوت کنی.»"}],"en":[{"v":1,"t":"I saw a mighty angel coming down out of the sky, clothed with a cloud. A rainbow was on his head. His face was like the sun, and his feet like pillars of fire."},{"v":2,"t":"He had in his hand a little open book. He set his right foot on the sea, and his left on the land."},{"v":3,"t":"He cried with a loud voice, as a lion roars. When he cried, the seven thunders uttered their voices."},{"v":4,"t":"When the seven thunders sounded, I was about to write; but I heard a voice from the sky saying, “Seal up the things which the seven thunders said, and don’t write them.”"},{"v":5,"t":"The angel whom I saw standing on the sea and on the land lifted up his right hand to the sky"},{"v":6,"t":"and swore by him who lives forever and ever, who created heaven and the things that are in it, the earth and the things that are in it, and the sea and the things that are in it, that there will no longer be delay,"},{"v":7,"t":"but in the days of the voice of the seventh angel, when he is about to sound, then the mystery of God is finished, as he declared to his servants the prophets."},{"v":8,"t":"The voice which I heard from heaven, again speaking with me, said, “Go, take the book which is open in the hand of the angel who stands on the sea and on the land.”"},{"v":9,"t":"I went to the angel, telling him to give me the little book. He said to me, “Take it and eat it. It will make your stomach bitter, but in your mouth it will be as sweet as honey.”"},{"v":10,"t":"I took the little book out of the angel’s hand, and ate it. It was as sweet as honey in my mouth. When I had eaten it, my stomach was made bitter."},{"v":11,"t":"They told me, “You must prophesy again over many peoples, nations, languages, and kings.”"}],"hr":[{"v":1,"t":"I vidjeh drugoga jednog, snažnog anđela: silazio s neba ogrnut oblakom, na glavi mu duga, lice mu kao sunce, a noge kao ognjeno stupovlje;"},{"v":2,"t":"u ruci drži otvorenu knjižicu. I zakorači desnom nogom na more, lijevom na zemlju pa povika iza glasa kao kad lav riče."},{"v":3,"t":"I kad povika, oglasi se sedam gromova tutnjavom."},{"v":4,"t":"A kad se oglasi sedam gromova, htjedoh pisati, ali začujem glas s neba: “Zapečati to što prozbori sedam gromova! Toga ne piši!”"},{"v":5,"t":"I onaj anđeo što ga vidjeh gdje stoji na moru i zemlji, podiže k nebu desnicu"},{"v":6,"t":"i zakle se Živim u vijeke vjekova, koji stvori nebo i sve što je na njemu, zemlju i sve što je na njoj, more i sve što je u njemu: “Neće više biti vremena!"},{"v":7,"t":"Nego - u dane kad se oglasi sedmi anđeo, čim zatrubi, dovršit će se otajstvo Božje kao što on to navijesti slugama svojim prorocima.”"},{"v":8,"t":"I glas što ga začuh s neba opet prozbori sa mnom: “Idi, uzmi otvorenu knjigu iz ruke anđela što stoji na moru i na zemlji!”"},{"v":9,"t":"Pristupim k anđelu i zamolim ga da mi dade knjižicu. A on će mi: “Uzmi je i progutaj! Zagorčit će ti utrobu, ali će ti u ustima biti slatka kao med.”"},{"v":10,"t":"Uzeh knjižicu iz ruke anđelove i progutah je. I bijaše mi u ustima kao med slatka, ali kad je progutah, zagorči mi utrobu."},{"v":11,"t":"I rečeno mi je: “Treba da ponovno prorokuješ proti pucima i narodima i kraljevima mnogim!”"}]},"11":{"fa":[{"v":1,"t":"و نی‌ای مثل عصا به من داده شد و مراگفت: «برخیز و قدس خدا و مذبح وآنانی را که در آن عبادت می‌کنند پیمایش نما."},{"v":2,"t":"وصحن خارج قدس را بیرون انداز و آن را مپیمازیرا که به امت‌ها داده شده است و شهر مقدس راچهل و دو ماه پایمال خواهند نمود."},{"v":3,"t":"و به دوشاهد خود خواهم داد که پلاس در بر کرده، مدت هزار و دویست و شصت روز نبوت نمایند.»"},{"v":4,"t":"اینانند دو درخت زیتون و دو چراغدان که در حضور خداوند زمین ایستاده‌اند."},{"v":5,"t":"و اگر کسی بخواهد بدیشان اذیت رساند، آتشی از دهانشان بدر شده، دشمنان ایشان را فرو می‌گیرد؛ و هر‌که قصد اذیت ایشان دارد، بدینگونه باید کشته شود."},{"v":6,"t":"اینها قدرت به بستن آسمان دارند تا در ایام نبوت ایشان باران نبارد و قدرت بر آبها دارند که آنها را به خون تبدیل نمایند و جهان را هر گاه بخواهند، به انواع بلایا مبتلا سازند."},{"v":7,"t":"و چون شهادت خود را به اتمام رسانند، آن وحش که از هاویه برمی آید، با ایشان جنگ کرده، غلبه خواهد یافت و ایشان را خواهد کشت"},{"v":8,"t":"وبدنهای ایشان در شارع عام شهر عظیم که به‌معنی روحانی، به سدوم و مصر مسمی است، جایی که خداوند ایشان نیز مصلوب گشت، خواهد ماند."},{"v":9,"t":"و گروهی از اقوام و قبایل و زبانها و امت‌ها، بدنهای ایشان را سه روز و نیم نظاره می‌کنند واجازت نمی دهند که بدنهای ایشان را به قبرسپارند."},{"v":10,"t":"و ساکنان زمین بر ایشان خوشی وشادی می‌کنند و نزد یکدیگر هدایا خواهندفرستاد، از آنرو که این دو نبی ساکنان زمین رامعذب ساختند."},{"v":11,"t":"و بعد از سه روز و نیم، روح حیات از خدابدیشان درآمد که بر پایهای خود ایستادند وبینندگان ایشان را خوفی عظیم فرو گرفت."},{"v":12,"t":"وآوازی بلند از آسمان شنیدند که بدیشان می‌گوید: «به اینجا صعود نمایید.» پس در ابر، به آسمان بالا شدند و دشمنانشان ایشان را دیدند."},{"v":13,"t":"و در همان ساعت، زلزله‌ای عظیم حادث گشت که ده‌یک از شهر منهدم گردید و هفت هزارنفر از زلزله هلاک شدند و باقی ماندگان ترسان گشته، خدای آسمان را تمجید کردند."},{"v":14,"t":"وای دوم درگذشته است. اینک وای سوم بزودی می‌آید."},{"v":15,"t":"و فرشته‌ای بنواخت که ناگاه صداهای بلنددر آسمان واقع شد که می‌گفتند: «سلطنت جهان از آن خداوند ما و مسیح او شد و تا ابدالابادحکمرانی خواهد کرد.»"},{"v":16,"t":"و آن بیست و چهارپیر که در حضور خدا بر تختهای خود نشسته‌اند، به روی درافتاده، خدا را سجده کردند"},{"v":17,"t":"و گفتند: «تو را شکر می‌کنیم‌ای خداوند، خدای قادرمطلق که هستی و بودی، زیرا که قوت عظیم خودرا بدست گرفته، به سلطنت پرداختی."},{"v":18,"t":"و امت هاخشمناک شدند و غضب تو ظاهر گردید و وقت مردگان رسید تا بر ایشان داوری شود و تا بندگان خود یعنی انبیا و مقدسان و ترسندگان نام خود راچه کوچک و چه بزرگ اجرت دهی و مفسدان زمین را فاسد گردانی.»"},{"v":19,"t":"و قدس خدا در آسمان مفتوح گشت وتابوت عهدنامه او در قدس او ظاهر شد و برقها وصداها و رعدها و زلزله و تگرگ عظیمی حادث شد."}],"en":[{"v":1,"t":"A reed like a rod was given to me. Someone said, “Rise and measure God’s temple, and the altar, and those who worship in it."},{"v":2,"t":"Leave out the court which is outside of the temple, and don’t measure it, for it has been given to the nations. They will tread the holy city under foot for forty-two months."},{"v":3,"t":"I will give power to my two witnesses, and they will prophesy one thousand two hundred sixty days, clothed in sackcloth.”"},{"v":4,"t":"These are the two olive trees and the two lamp stands, standing before the Lord of the earth."},{"v":5,"t":"If anyone desires to harm them, fire proceeds out of their mouth and devours their enemies. If anyone desires to harm them, he must be killed in this way."},{"v":6,"t":"These have the power to shut up the sky, that it may not rain during the days of their prophecy. They have power over the waters, to turn them into blood, and to strike the earth with every plague, as often as they desire."},{"v":7,"t":"When they have finished their testimony, the beast that comes up out of the abyss will make war with them, and overcome them, and kill them."},{"v":8,"t":"Their dead bodies will be in the street of the great city, which spiritually is called Sodom and Egypt, where also their Lord was crucified."},{"v":9,"t":"From among the peoples, tribes, languages, and nations, people will look at their dead bodies for three and a half days, and will not allow their dead bodies to be laid in a tomb."},{"v":10,"t":"Those who dwell on the earth will rejoice over them, and they will be glad. They will give gifts to one another, because these two prophets tormented those who dwell on the earth."},{"v":11,"t":"After the three and a half days, the breath of life from God entered into them, and they stood on their feet. Great fear fell on those who saw them."},{"v":12,"t":"I heard a loud voice from heaven saying to them, “Come up here!” They went up into heaven in a cloud, and their enemies saw them."},{"v":13,"t":"In that day there was a great earthquake, and a tenth of the city fell. Seven thousand people were killed in the earthquake, and the rest were terrified and gave glory to the God of heaven."},{"v":14,"t":"The second woe is past. Behold, the third woe comes quickly."},{"v":15,"t":"The seventh angel sounded, and great voices in heaven followed, saying, “The kingdom of the world has become the Kingdom of our Lord and of his Christ. He will reign forever and ever!”"},{"v":16,"t":"The twenty-four elders, who sit on their thrones before God’s throne, fell on their faces and worshiped God,"},{"v":17,"t":"saying: “We give you thanks, Lord God, the Almighty, the one who is and who was, because you have taken your great power and reigned."},{"v":18,"t":"The nations were angry, and your wrath came, as did the time for the dead to be judged, and to give your bondservants the prophets, their reward, as well as to the saints and those who fear your name, to the small and the great, and to destroy those who destroy the earth.”"},{"v":19,"t":"God’s temple that is in heaven was opened, and the ark of the Lord’s covenant was seen in his temple. Lightnings, sounds, thunders, an earthquake, and great hail followed."}],"hr":[{"v":1,"t":"I dana mi je trska slična palici i rečeno mi je: “Ustani i izmjeri hram Božji i žrtvenik i poklonike u njemu!"},{"v":2,"t":"Vanjsko dvorište hrama mimoiđi, ne mjeri ga jer je dano poganima: gazit će svetim gradom četrdeset i dva mjeseca."},{"v":3,"t":"I ja ću poslati dva svoja svjedoka da, obučeni u kostrijet, prorokuju tisuću dvjesta i šezdeset dana."},{"v":4,"t":"Oni su dvije masline i dva svijećnjaka što stoje pred Gospodarom zemlje."},{"v":5,"t":"Ako im tko hoće nauditi, oganj suče iz usta njihovih i proždire njihove neprijatelje. Doista, htjedne li im tko nauditi, tako treba da pogine."},{"v":6,"t":"Oni imaju vlast zaključati nebo da ne pada kiša dok prorokuju; imaju vlast pretvoriti vode u krv i udariti zemlju kojim god zlom kad god htjednu."},{"v":7,"t":"A kada dovrše svoje svjedočanstvo, Zvijer koja izlazi iz Bezdana zaratit će s njima, pobijediti ih i ubiti."},{"v":8,"t":"I njihova će trupla ležati na trgu grada velikoga koji se duhovno zove Sodoma i Egipat, gdje je i Gospodin njihov raspet."},{"v":9,"t":"Ljudi iz svih puka i plemena i jezika i naroda gledat će njihova trupla tri i pol dana i neće dopustiti da im se trupla u grob polože."},{"v":10,"t":"Pozemljari će se radovati i veseliti zbog njihove nesreće i darivati jedan drugoga jer su ta dva proroka zadavala muku pozemljarima."},{"v":11,"t":"Ali nakon tri i pol dana duh životni od Boga uđe u njih i stadoše na noge te strah velik obuze one koji ih promatrahu."},{"v":12,"t":"I začuše glas s neba silan: “Uziđite ovamo!” I uziđoše na oblaku u nebo na očigled svojih neprijatelja."},{"v":13,"t":"U taj čas nasta velik potres: pade desetina grada, a u potresu poginu sedam tisuća ljudi. Preživjele spopade strah te proslaviše Boga nebeskoga."},{"v":14,"t":"Drugi Jao prođe. Evo, treći Jao dolazi ubrzo!"},{"v":15,"t":"I sedmi anđeo zatrubi. I na nebu odjeknuše silni glasovi: “Uspostavljeno je nad svijetom kraljevstvo Gospodara našega i Pomazanika njegova i kraljevat će u vijeke vjekova!”"},{"v":16,"t":"Tada dvadeset i četiri starješine, što pred Bogom sjedoše na prijestolja,"},{"v":17,"t":"padoše ničice i pokloniše se Bogu govoreći. “Zahvaljujemo ti, Gospodaru, Bože, Svevladaru, koji jesi i koji bijaše, zato što uze u ruke moć svoju veliku i zakralji se!"},{"v":18,"t":"Gnjevili se narodi, ali dođe srdžba tvoja i čas da se sudi mrtvima i naplata dade slugama tvojim prorocima i svetima i svima koji se boje imena tvojega, malima i velikima; i da se unište oni koji kvare zemlju.”"},{"v":19,"t":"I otvori se hram Božji na nebu i pokaza se Kovčeg saveza njegova u hramu njegovu te udare munje i glasovi i gromovi i potres i tuča velika."}]},"12":{"fa":[{"v":1,"t":"و علامتی عظیم در آسمان ظاهر شد: زنی که آفتاب را دربر دارد و ماه زیرپایهایش و بر سرش تاجی از دوازده ستاره است،"},{"v":2,"t":"و آبستن بوده، از درد زه و عذاب زاییدن فریاد برمی آورد."},{"v":3,"t":"و علامتی دیگر در آسمان پدید آمدکه اینک اژدهای بزرگ آتشگون که او را هفت سرو ده شاخ بود و بر سرهایش هفت افسر؛"},{"v":4,"t":"و دمش ثلث ستارگان آسمان را کشیده، آنها را بر زمین ریخت. و اژدها پیش آن زن که می‌زایید بایستاد تاچون بزاید فرزند او را ببلعد."},{"v":5,"t":"پس پسر نرینه‌ای را زایید که همه امت های زمین را به عصای آهنین حکمرانی خواهد کرد؛ و فرزندش به نزد خدا وتخت او ربوده شد."},{"v":6,"t":"و زن به بیابان فرار کرد که درآنجا مکانی برای وی از خدا مهیا شده است تا اورا مدت هزار و دویست و شصت روز بپرورند."},{"v":7,"t":"و در آسمان جنگ شد: میکائیل وفرشتگانش با اژدها جنگ کردند و اژدها وفرشتگانش جنگ کردند،"},{"v":8,"t":"ولی غلبه نیافتند بلکه جای ایشان دیگر در آسمان یافت نشد."},{"v":9,"t":"واژدهای بزرگ انداخته شد، یعنی آن مار قدیمی که به ابلیس و شیطان مسمی است که تمام ربع مسکون را می‌فریبد. او بر زمین انداخته شد وفرشتگانش با وی انداخته شدند."},{"v":10,"t":"و آوازی بلند در آسمان شنیدم که می‌گوید: «اکنون نجات و قوت و سلطنت خدای ما و قدرت مسیح او ظاهر شد زیرا که آن مدعی برادران ما که شبانه‌روز در حضور خدای ما برایشان دعوی می‌کند، به زیر افکنده شد."},{"v":11,"t":"وایشان بوساطت خون بره و کلام شهادت خود براو غالب آمدند و جان خود را دوست نداشتند."},{"v":12,"t":"از این جهت‌ای آسمانها و ساکنان آنها شادباشید؛ وای بر زمین و دریا زیرا که ابلیس به نزدشما فرود شده است با خشم عظیم، چون می‌داند که زمانی قلیل دارد.»"},{"v":13,"t":"و چون اژدها دید که بر زمین افکنده شد، برآن زن که فرزند نرینه را زاییده بود، جفا کرد."},{"v":14,"t":"ودو بال عقاب بزرگ به زن داده شد تا به بیابان به مکان خود پرواز کند، جایی که او را از نظر آن مار، زمانی و دو زمان و نصف زمان پرورش می‌کنند."},{"v":15,"t":"و مار از دهان خود در عقب زن، آبی چون رودی ریخت تا سیل او را فرو‌گیرد."},{"v":16,"t":"وزمین زن را حمایت کرد و زمین دهان خود راگشاده، آن رود را که اژدها از دهان خود ریخت فرو برد."},{"v":17,"t":"و اژدها بر زن غضب نموده، رفت تا باباقی ماندگان ذریت او که احکام خدا را حفظمی کنند و شهادت عیسی را نگاه می‌دارند، جنگ کند."}],"en":[{"v":1,"t":"A great sign was seen in heaven: a woman clothed with the sun, and the moon under her feet, and on her head a crown of twelve stars."},{"v":2,"t":"She was with child. She cried out in pain, laboring to give birth."},{"v":3,"t":"Another sign was seen in heaven. Behold, a great red dragon, having seven heads and ten horns, and on his heads seven crowns."},{"v":4,"t":"His tail drew one third of the stars of the sky, and threw them to the earth. The dragon stood before the woman who was about to give birth, so that when she gave birth he might devour her child."},{"v":5,"t":"She gave birth to a son, a male child, who is to rule all the nations with a rod of iron. Her child was caught up to God and to his throne."},{"v":6,"t":"The woman fled into the wilderness, where she has a place prepared by God, that there they may nourish her one thousand two hundred sixty days."},{"v":7,"t":"There was war in the sky. Michael and his angels made war on the dragon. The dragon and his angels made war."},{"v":8,"t":"They didn’t prevail. No place was found for them any more in heaven."},{"v":9,"t":"The great dragon was thrown down, the old serpent, he who is called the devil and Satan, the deceiver of the whole world. He was thrown down to the earth, and his angels were thrown down with him."},{"v":10,"t":"I heard a loud voice in heaven, saying, “Now the salvation, the power, and the Kingdom of our God, and the authority of his Christ has come; for the accuser of our brothers has been thrown down, who accuses them before our God day and night."},{"v":11,"t":"They overcame him because of the Lamb’s blood, and because of the word of their testimony. They didn’t love their life, even to death."},{"v":12,"t":"Therefore rejoice, heavens, and you who dwell in them. Woe to the earth and to the sea, because the devil has gone down to you, having great wrath, knowing that he has but a short time.”"},{"v":13,"t":"When the dragon saw that he was thrown down to the earth, he persecuted the woman who gave birth to the male child."},{"v":14,"t":"Two wings of the great eagle were given to the woman, that she might fly into the wilderness to her place, so that she might be nourished for a time, times, and half a time, from the face of the serpent."},{"v":15,"t":"The serpent spewed water out of his mouth after the woman like a river, that he might cause her to be carried away by the stream."},{"v":16,"t":"The earth helped the woman, and the earth opened its mouth and swallowed up the river which the dragon spewed out of his mouth."},{"v":17,"t":"The dragon grew angry with the woman, and went away to make war with the rest of her offspring, who keep God’s commandments and hold Jesus’ testimony."}],"hr":[{"v":1,"t":"I znamenje veliko pokaza se na nebu: Žena odjevena suncem, mjesec joj pod nogama, a na glavi vijenac od dvanaest zvijezda."},{"v":2,"t":"Trudna viče u porođajnim bolima i mukama rađanja."},{"v":3,"t":"I pokaza se drugo znamenje na nebu: gle, Zmaj velik, ognjen, sa sedam glava i deset rogova; na glavama mu sedam kruna,"},{"v":4,"t":"a rep mu povlači trećinu zvijezda nebeskih - i obori ih na zemlju. Zmaj stade pred Ženu koja imaše roditi da joj, čim rodi, proždre Dijete."},{"v":5,"t":"I ona porodi sina, muškića, koji će vladati svim narodima palicom gvozdenom. I Dijete njeno bi uzeto k Bogu i prijestolju njegovu."},{"v":6,"t":"A Žena pobježe u pustinju gdje joj Bog pripravi sklonište da se ondje hrani tisuću dvjesta i šezdeset dana."},{"v":7,"t":"I nasta rat na nebu: Mihael i njegovi anđeli zarate se sa Zmajem. Zmaj uđe u rat i anđeli njegovi,"},{"v":8,"t":"ali ne nadvlada. I ne bijaše im više mjesta na nebu."},{"v":9,"t":"Zbačen je Zmaj veliki, Stara zmija - imenom Ðavao, Sotona, zavodnik svega svijeta. Bačen je na zemlju, a s njime su bačeni i anđeli njegovi."},{"v":10,"t":"I začujem glas na nebu silan: “Sada nasta spasenje i snaga i kraljevstvo Boga našega i vlast Pomazanika njegova! Jer zbačen je tužitelj braće naše koji ih je dan i noć optuživao pred Bogom našim."},{"v":11,"t":"Ali oni ga pobijediše krvlju Jaganjčevom i riječju svojega svjedočanstva: nisu ljubili života svoga - sve do smrti."},{"v":12,"t":"Zato veselite se, nebesa i svi nebesnici! A jao vama, zemljo i more, jer Ðavao siđe k vama, gnjevan veoma, znajući da ima malo vremena!”"},{"v":13,"t":"Kad Zmaj vidje da je zbačen na zemlju, stade progoniti Ženu koja rodi muškića."},{"v":14,"t":"No Ženi bijahu dana dva velika krila orlujska da odleti u pustinju, u svoje sklonište gdje se, sklonjena od Zmije, hrani jedno vrijeme i dva vremena i polovicu vremena."},{"v":15,"t":"I Zmija iz usta pusti za Ženom vodu poput rijeke da je rijeka odnese."},{"v":16,"t":"Ali zemlja priteče u pomoć Ženi: otvori usta i popi rijeku što je Zmaj pusti iz usta."},{"v":17,"t":"I razgnjevi se Zmaj na Ženu pa ode i zarati se s ostatkom njezina potomstva, s onima što čuvaju Božje zapovijedi i drže svjedočanstvo Isusovo."},{"v":18,"t":"I stade na morski žal."}]},"13":{"fa":[{"v":1,"t":"و او بر ریگ دریا ایستاده بود."},{"v":2,"t":"و آن وحش را که دیدم، مانند پلنگ بود و پایهایش مثل پای خرس و دهانش مثل دهان شیر. و اژدها قوت خویش وتخت خود و قوت عظیمی به وی داد."},{"v":3,"t":"و یکی ازسرهایش را دیدم که تا به موت کشته شد و از آن زخم مهلک شفا یافت و تمامی جهان در‌پی این وحش در حیرت افتادند."},{"v":4,"t":"و آن اژدها را که قدرت به وحش داده بود، پرستش کردند و وحش را سجده کرده، گفتند که «کیست مثل وحش وکیست که با وی می‌تواند جنگ کند؟»"},{"v":5,"t":"و به وی دهانی داده شد که به کبر و کفر تکلم می‌کند؛ و قدرتی به او عطا شد که مدت چهل ودو ماه عمل کند."},{"v":6,"t":"پس دهان خود را به کفرهای برخدا گشود تا بر اسم او و خیمه او و سکنه آسمان کفر گوید."},{"v":7,"t":"و به وی داده شد که با مقدسین جنگ کند و بر ایشان غلبه یابد؛ و تسلط بر هر قبیله وقوم و زبان و امت، بدو عطا شد."},{"v":8,"t":"و جمیع ساکنان جهان، جز آنانی که نامهای ایشان در دفتر حیات بره‌ای که از بنای عالم ذبح شده بود مکتوب است، او را خواهند پرستید."},{"v":9,"t":"اگر کسی گوش داردبشنود."},{"v":10,"t":"اگر کسی اسیر نماید به اسیری رود، واگر کسی به شمشیر قتل کند، می‌باید او به شمشیرکشته گردد. در اینجاست صبر و ایمان مقدسین."},{"v":11,"t":"و دیدم وحش دیگری را که از زمین بالامی آید و دو شاخ مثل شاخهای بره داشت و ماننداژدها تکلم می‌نمود؛"},{"v":12,"t":"و با تمام قدرت وحش نخست، در حضور وی عمل می‌کند و زمین وسکنه آن را بر این وامی دارد که وحش نخست راکه از زخم مهلک شفا یافت، بپرستند."},{"v":13,"t":"ومعجزات عظیمه بعمل می‌آورد تا آتش را نیز ازآسمان در حضور مردم به زمین فرود آورد."},{"v":14,"t":"وساکنان زمین را گمراه می‌کند، به آن معجزاتی که به وی داده شد که آنها را در حضور وحش بنماید. و به ساکنان زمین می‌گوید که صورتی را ازآن وحش که بعد از خوردن زخم شمشیر زیست نمود، بسازند."},{"v":15,"t":"و به وی داده شد که آن صورت وحش را روح بخشد تا که صورت وحش سخن گوید و چنان کند که هر‌که صورت وحش راپرستش نکند، کشته گردد."},{"v":16,"t":"و همه را از کبیرو صغیر و دولتمند و فقیر و غلام و آزاد براین وامی دارد که بر دست راست یا برپیشانی خود نشانی گذارند."},{"v":17,"t":"و اینکه هیچ‌کس خرید و فروش نتواند کرد، جز کسی‌که نشان یعنی اسم یا عدد اسم وحش را داشته باشد."},{"v":18,"t":"در اینجا حکمت است. پس هر‌که فهم دارد، عدد وحش را بشمارد، زیرا که عددانسان است و عددش ششصد و شصت و شش است."}],"en":[{"v":1,"t":"Then I stood on the sand of the sea. I saw a beast coming up out of the sea, having ten horns and seven heads. On his horns were ten crowns, and on his heads, blasphemous names."},{"v":2,"t":"The beast which I saw was like a leopard, and his feet were like those of a bear, and his mouth like the mouth of a lion. The dragon gave him his power, his throne, and great authority."},{"v":3,"t":"One of his heads looked like it had been wounded fatally. His fatal wound was healed, and the whole earth marveled at the beast."},{"v":4,"t":"They worshiped the dragon because he gave his authority to the beast; and they worshiped the beast, saying, “Who is like the beast? Who is able to make war with him?”"},{"v":5,"t":"A mouth speaking great things and blasphemy was given to him. Authority to make war for forty-two months was given to him."},{"v":6,"t":"He opened his mouth for blasphemy against God, to blaspheme his name, his dwelling, and those who dwell in heaven."},{"v":7,"t":"It was given to him to make war with the saints and to overcome them. Authority over every tribe, people, language, and nation was given to him."},{"v":8,"t":"All who dwell on the earth will worship him, everyone whose name has not been written from the foundation of the world in the book of life of the Lamb who has been killed."},{"v":9,"t":"If anyone has an ear, let him hear."},{"v":10,"t":"If anyone is to go into captivity, he will go into captivity. If anyone is to be killed with the sword, he must be killed. Here is the endurance and the faith of the saints."},{"v":11,"t":"I saw another beast coming up out of the earth. He had two horns like a lamb and it spoke like a dragon."},{"v":12,"t":"He exercises all the authority of the first beast in his presence. He makes the earth and those who dwell in it to worship the first beast, whose fatal wound was healed."},{"v":13,"t":"He performs great signs, even making fire come down out of the sky to the earth in the sight of people."},{"v":14,"t":"He deceives my own people who dwell on the earth because of the signs he was granted to do in front of the beast, saying to those who dwell on the earth that they should make an image to the beast who had the sword wound and lived."},{"v":15,"t":"It was given to him to give breath to the image of the beast, that the image of the beast should both speak, and cause as many as wouldn’t worship the image of the beast to be killed."},{"v":16,"t":"He causes all, the small and the great, the rich and the poor, and the free and the slave, to be given marks on their right hands or on their foreheads;"},{"v":17,"t":"and that no one would be able to buy or to sell unless he has that mark, which is the name of the beast or the number of his name."},{"v":18,"t":"Here is wisdom. He who has understanding, let him calculate the number of the beast, for it is the number of a man. His number is six hundred sixty-six."}],"hr":[{"v":1,"t":"I vidjeh: iz mora Zvijer izlazi sa deset rogova i sedam glava; na rogovima joj deset kruna, na glavama bogohulna imena."},{"v":2,"t":"Ta Zvijer što je vidjeh bijaše nalik na leoparda, noge joj kao medvjeđe, usta kao usta lavlja. Zmaj joj dade svoju silu i prijestolje i vlast veliku."},{"v":3,"t":"Jedna joj glava bijaše kao na smrt zaklana, ali joj se smrtna rana zaliječila. Sva se zemlja, začuđena, zanijela za Zvijeri"},{"v":4,"t":"i svi se pokloniše Zmaju koji dade takvu vlast Zvijeri. Pokloniše se i Zvijeri govoreći: “Tko je kao Zvijer! Tko bi smio ratovati s njom?”"},{"v":5,"t":"I dana su joj usta da govori drskosti i hule i dana joj je vlast da to čini četrdeset i dva mjeseca."},{"v":6,"t":"I ona otvori usta da huli Boga, da huli ime njegovo, njegov Šator i nebesnike."},{"v":7,"t":"I dano joj je da se zarati sa svecima i da ih pobijedi. Dana joj je vlast nad svakim plemenom i pukom i jezikom i narodom:"},{"v":8,"t":"da joj se poklone svi pozemljari, oni kojima ime nije zapisano u knjizi života zaklanog Jaganjca, od postanka svijeta."},{"v":9,"t":"Tko ima uho, nek posluša!"},{"v":10,"t":"Je li tko za progonstvo, u progonstvo će ići! Je li tko za mač, da bude pogubljen, mačem će biti pogubljen! U tom je postojanost i vjera svetih."},{"v":11,"t":"I vidjeh: druga jedna Zvijer uzlazi iz zemlje, ima dva roga poput jaganjca, a govori kao Zmaj."},{"v":12,"t":"Vrši svu vlast one prve Zvijeri, u njenoj nazočnosti. Prisiljava zemlju i sve pozemljare da se poklone prvoj Zvijeri kojoj ono zacijeli smrtna rana."},{"v":13,"t":"Čini znamenja velika: i oganj spušta s neba na zemlju naočigled ljudi."},{"v":14,"t":"Tako zavodi pozemljare znamenjima koja joj je dano činiti u nazočnosti Zvijeri: svjetuje pozemljarima da načine kip Zvijeri koja bijaše udarena mačem, ali preživje."},{"v":15,"t":"I dano joj je udahnuti život kipu Zvijeri te kip Zvijeri progovori i poubija sve koji se god ne klanjaju kipu Zvijeri."},{"v":16,"t":"Ona postiže da se svima - malima i velikima, bogatima i ubogima, slobodnjacima i robovima - udari žig na desnicu ili na čelo,"},{"v":17,"t":"i da nitko ne mogne kupovati ili prodavati osim onog koji nosi žig s imenom Zvijeri ili s brojem imena njezina."},{"v":18,"t":"U ovome je mudrost: u koga je uma, nek odgoneta broj Zvijeri. Broj je to jednog čovjeka, a broj mu je šest stotina šezdeset i šest."}]},"14":{"fa":[{"v":1,"t":"و دیدم که اینک بره، بر کوه صهیون ایستاده است و با وی صد و چهل وچهار هزار نفر که اسم او و اسم پدر او را بر پیشانی خود مرقوم می‌دارند."},{"v":2,"t":"و آوازی از آسمان شنیدم، مثل آواز آبهای بسیار و مانند آواز رعدعظیم؛ و آن آوازی که شنیدم، مانند آوازبربطنوازان بود که بربطهای خود را بنوازند."},{"v":3,"t":"و درحضور تخت و چهار حیوان و پیران، سرودی جدید می‌سرایند و هیچ‌کس نتوانست آن سرودرا بیاموزد، جز آن صد و چهل و چهار هزار که ازجهان خریده شده بودند."},{"v":4,"t":"اینانند آنانی که با زنان آلوده نشدند، زیرا که باکره هستند؛ و آنانند که بره را هر کجا می‌رود متابعت می‌کنند و از میان مردم خریده شده‌اند تا نوبر برای خدا و بره باشند."},{"v":5,"t":"ودر دهان ایشان دروغی یافت نشد، زیرا که بی‌عیب هستند."},{"v":6,"t":"و فرشته‌ای دیگر را دیدم که در وسط آسمان پرواز می‌کند و انجیل جاودانی را دارد تا ساکنان زمین را از هر امت و قبیله و زبان و قوم بشارت دهد،"},{"v":7,"t":"و به آواز بلند می‌گوید: «از خدا بترسید واو را تمجید نمایید، زیرا که زمان داوری اورسیده است. پس او را که آسمان و زمین و دریا وچشمه های آب را آفرید، پرستش کنید.»"},{"v":8,"t":"و فرشته‌ای دیگر از عقب او آمده، گفت: «منهدم شد بابل عظیم که از خمر غضب زنای خود، جمیع امت‌ها را نوشانید.»"},{"v":9,"t":"و فرشته سوم از عقب این دو آمده، به آوازبلند می‌گوید: «اگر کسی وحش و صورت او راپرستش کند و نشان او را بر پیشانی یا دست خودپذیرد،"},{"v":10,"t":"او نیز از خمر غضب خدا که در‌پیاله خشم وی بیغش آمیخته شده است، خواهدنوشید، و در نزد فرشتگان مقدس و در حضوربره، به آتش و کبریت، معذب خواهد شد،"},{"v":11,"t":"ودود عذاب ایشان تا ابدالاباد بالا می‌رود. پس آنانی که وحش و صورت او را پرستش می‌کنند وهر‌که نشان اسم او را پذیرد، شبانه‌روز آرامی ندارند.»"},{"v":12,"t":"در اینجاست صبر مقدسین که احکام خدا و ایمان عیسی را حفظ می‌نمایند."},{"v":13,"t":"و آوازی را از آسمان شنیدم که می‌گوید: «بنویس که از کنون خوشحالند مردگانی که درخداوند می‌میرند. و روح می‌گوید: «بلی، تا از زحمات خودآرامی یابند و اعمال ایشان از عقب ایشان می‌رسد.»"},{"v":14,"t":"و دیدم که اینک ابری سفید پدید آمد و برابر، کسی مثل پسر انسان نشسته که تاجی از طلادارد و در دستش داسی تیز است."},{"v":15,"t":"و فرشته‌ای دیگر از قدس بیرون آمده، به آواز بلند آن ابرنشین را ندا می‌کند که داس خود را پیش بیاور و درو کن، زیرا هنگام حصاد رسیده و حاصل زمین خشک شده است."},{"v":16,"t":"و ابرنشین داس خود را بر زمین آورد و زمین درویده شد."},{"v":17,"t":"و فرشته‌ای دیگر از قدسی که در آسمان است، بیرون آمد و او نیز داسی تیز داشت."},{"v":18,"t":"وفرشته‌ای دیگر که بر آتش مسلط است، از مذبح بیرون شده، به آواز بلند ندا در‌داده، صاحب داس تیز را گفت: «داس تیز خود را پیش آور وخوشه های مو زمین را بچین، زیرا انگورهایش رسیده است.»"},{"v":19,"t":"پس آن فرشته داس خود را برزمین آورد و موهای زمین را چیده، آن را درچرخشت عظیم غضب خدا ریخت."},{"v":20,"t":"وچرخشت را بیرون شهر به پا بیفشردند و خون ازچرخشت تا به دهن اسبان به مسافت هزار وششصد تیر پرتاب جاری شد."}],"en":[{"v":1,"t":"I saw, and behold, the Lamb standing on Mount Zion, and with him a number, one hundred forty-four thousand, having his name and the name of his Father written on their foreheads."},{"v":2,"t":"I heard a sound from heaven like the sound of many waters and like the sound of a great thunder. The sound which I heard was like that of harpists playing on their harps."},{"v":3,"t":"They sing a new song before the throne and before the four living creatures and the elders. No one could learn the song except the one hundred forty-four thousand, those who had been redeemed out of the earth."},{"v":4,"t":"These are those who were not defiled with women, for they are virgins. These are those who follow the Lamb wherever he goes. These were redeemed by Jesus from among men, the first fruits to God and to the Lamb."},{"v":5,"t":"In their mouth was found no lie, for they are blameless."},{"v":6,"t":"I saw an angel flying in mid heaven, having an eternal Good News to proclaim to those who dwell on the earth—to every nation, tribe, language, and people."},{"v":7,"t":"He said with a loud voice, “Fear the Lord, and give him glory, for the hour of his judgment has come. Worship him who made the heaven, the earth, the sea, and the springs of waters!”"},{"v":8,"t":"Another, a second angel, followed, saying, “Babylon the great has fallen, which has made all the nations to drink of the wine of the wrath of her sexual immorality.”"},{"v":9,"t":"Another angel, a third, followed them, saying with a great voice, “If anyone worships the beast and his image, and receives a mark on his forehead or on his hand,"},{"v":10,"t":"he also will drink of the wine of the wrath of God, which is prepared unmixed in the cup of his anger. He will be tormented with fire and sulfur in the presence of the holy angels and in the presence of the Lamb."},{"v":11,"t":"The smoke of their torment goes up forever and ever. They have no rest day and night, those who worship the beast and his image, and whoever receives the mark of his name."},{"v":12,"t":"Here is the perseverance of the saints, those who keep the commandments of God and the faith of Jesus.”"},{"v":13,"t":"I heard a voice from heaven saying, “Write, ‘Blessed are the dead who die in the Lord from now on.’” “Yes,” says the Spirit, “that they may rest from their labors, for their works follow with them.”"},{"v":14,"t":"I looked, and saw a white cloud, and on the cloud one sitting like a son of man, having on his head a golden crown, and in his hand a sharp sickle."},{"v":15,"t":"Another angel came out of the temple, crying with a loud voice to him who sat on the cloud, “Send your sickle and reap, for the hour to reap has come; for the harvest of the earth is ripe!”"},{"v":16,"t":"He who sat on the cloud thrust his sickle on the earth, and the earth was reaped."},{"v":17,"t":"Another angel came out of the temple which is in heaven. He also had a sharp sickle."},{"v":18,"t":"Another angel came out from the altar, he who has power over fire, and he called with a great voice to him who had the sharp sickle, saying, “Send your sharp sickle and gather the clusters of the vine of the earth, for the earth’s grapes are fully ripe!”"},{"v":19,"t":"The angel thrust his sickle into the earth, and gathered the vintage of the earth and threw it into the great wine press of the wrath of God."},{"v":20,"t":"The wine press was trodden outside of the city, and blood came out of the wine press, up to the bridles of the horses, as far as one thousand six hundred stadia."}],"hr":[{"v":1,"t":"I vidjeh: gle, Jaganjac stoji na gori Sionu, a s njime sto četrdeset i četiri tisuće - na čelima im napisano ime njegovo i ime Oca njegova!"},{"v":2,"t":"I začujem s neba glas, kao šum voda mnogih i tutnjavu silna groma; glas taj koji začuh bijaše kao glas citraša što sviraju na citrama."},{"v":3,"t":"Pjevali su pjesmu novu pred prijestoljem i pred četiri bića i pred starješinama. Nitko ne mogaše naučiti te pjesme doli one sto četrdeset i četiri tisuće - otkupljeni sa zemlje."},{"v":4,"t":"Ti se ne okaljaše sa ženama, djevci su! Oni prate Jaganjca kamo god pođe. Otkupljeni su od ljudi kao prvine Bogu i Jaganjcu;"},{"v":5,"t":"na ustima se njihovim laž ne nađe, neporočni su."},{"v":6,"t":"I vidjeh: drugi jedan anđeo leti posred neba s evanđeljem vječnim da ga proglasi svim pozemljarima, svakom narodu i plemenu i jeziku i puku."},{"v":7,"t":"Viče iza glasa: “Bojte se Boga i dajte mu slavu jer dođe čas suda njegova! I poklonite se njemu koji stvori nebo i zemlju i more i izvore voda!”"},{"v":8,"t":"Za njim eto drugog anđela koji govori: “Pade, pade Babilon, veliki koji vinom gnjeva i bluda svojega opi sve narode!”"},{"v":9,"t":"Za njima eto i trećeg anđela koji vikaše iza glasa: “Tko god se klanja Zvijeri i kipu njezinu te primi žig na čelo ili ruku,"},{"v":10,"t":"pit će vino gnjeva Božjega, nerazvodnjeno, natočeno već u čaši srdžbe njegove! I bit će udaren na muke u ognju i sumporu svetim anđelima naočigled i naočigled Jaganjcu."},{"v":11,"t":"Dim muke njihove suklja u vijeke vjekova. Ni danju ni noću nemaju počinka oni koji se klanjaju Zvijeri i kipu njezinu i tko god primi žig s imenom njezinim.”"},{"v":12,"t":"U tom je postojanost svetih - onih što čuvaju zapovijedi Božje i vjeru Isusovu."},{"v":13,"t":"I začujem glas s neba: “Piši! Od sada blaženi mrtvi koji umiru u Gospodinu! Da, govori Duh, neka otpočinu od svojih trudova! Jer prate ih djela njihova!”"},{"v":14,"t":"I vidjeh: gle, bijel oblak, a na oblak sjede Netko kao Sin Čovječji; na glavi mu zlatan vijenac, u ruci oštar srp."},{"v":15,"t":"I drugi jedan anđeo iziđe iz hrama vičući iza glasa onomu što sjedi na oblaku: “Mahni srpom i žanji jer dođe čas žetvi, zrela je žetva zemaljska!”"},{"v":16,"t":"I onaj što sjedi na oblaku baci srp na zemlju i zemlja bi požnjevena."},{"v":17,"t":"I drugi jedan anđeo iziđe iz hrama nebeskoga. I on imaše oštar srp."},{"v":18,"t":"I od žrtvenika iziđe drugi anđeo - onaj koji ima vlast nad ognjem - pa povika iza glasa onomu, s oštrim srpom: “Mahni oštrim srpom i poberi grozdove u vinogradu zemaljskom jer sazri grožđe!”"},{"v":19,"t":"I anđeo baci srp na zemlju i obra vinograd zemaljski, a obrano baci u veliku kacu gnjeva Božjega."},{"v":20,"t":"Gazila se kaca izvan grada te poteče krv iz kace konjima do uzda, tisuću i šest stotina stadija uokolo."}]},"15":{"fa":[{"v":1,"t":"و علامت دیگر عظیم و عجیبی درآسمان دیدم، یعنی هفت فرشته‌ای که هفت بلایی دارند که آخرین هستند، زیرا که به آنها غضب الهی به انجام رسیده است."},{"v":2,"t":"و دیدم مثال دریایی از شیشه مخلوط به آتش و کسانی راکه بر وحش و صورت او و عدد اسم او غلبه می یابند، بر دریای شیشه ایستاده و بربطهای خدارا بدست گرفته،"},{"v":3,"t":"سرود موسی بنده خدا و سرودبره را می‌خوانند و می‌گویند: «عظیم و عجیب است اعمال تو‌ای خداوند خدای قادر مطلق! عدل و حق است راههای تو‌ای پادشاه امت‌ها."},{"v":4,"t":"کیست که از تو نترسد، خداوندا و کیست که نام تو را تمجید ننماید؟ زیرا که تو تنها قدوس هستی و جمیع امت‌ها آمده، در حضور توپرستش خواهند کرد، زیرا که احکام تو ظاهرگردیده است."},{"v":5,"t":"و بعد از این دیدم که قدس خیمه شهادت درآسمان گشوده شد،"},{"v":6,"t":"و هفت فرشته‌ای که هفت بلا داشتند، کتانی پاک و روشن دربر کرده و کمرایشان به کمربند زرین بسته، بیرون آمدند."},{"v":7,"t":"ویکی از آن چهار حیوان، به آن هفت فرشته، هفت پیاله زرین داد، پر از غضب خدا که تا ابدالاباد زنده است."},{"v":8,"t":"و قدس از جلال خدا و قوت او پر دودگردید."}],"en":[{"v":1,"t":"I saw another great and marvelous sign in the sky: seven angels having the seven last plagues, for in them God’s wrath is finished."},{"v":2,"t":"I saw something like a sea of glass mixed with fire, and those who overcame the beast, his image, and the number of his name, standing on the sea of glass, having harps of God."},{"v":3,"t":"They sang the song of Moses, the servant of God, and the song of the Lamb, saying, “Great and marvelous are your works, Lord God, the Almighty! Righteous and true are your ways, you King of the nations."},{"v":4,"t":"Who wouldn’t fear you, Lord, and glorify your name? For you only are holy. For all the nations will come and worship before you. For your righteous acts have been revealed.”"},{"v":5,"t":"After these things I looked, and the temple of the tabernacle of the testimony in heaven was opened."},{"v":6,"t":"The seven angels who had the seven plagues came out, clothed with pure, bright linen, and wearing golden sashes around their chests."},{"v":7,"t":"One of the four living creatures gave to the seven angels seven golden bowls full of the wrath of God, who lives forever and ever."},{"v":8,"t":"The temple was filled with smoke from the glory of God and from his power. No one was able to enter into the temple until the seven plagues of the seven angels would be finished."}],"hr":[{"v":1,"t":"I vidjeh drugo znamenje na nebu, veliko i čudesno: sedam anđela sa sedam zala posljednjih - s njima se navršuje gnjev Božji."},{"v":2,"t":"I vidjeh kao neko more od prozirca pomiješano s ognjem. Oni koji pobijediše Zvijer i kip njezin i broj imena njezina stoje u moru od prozirca s citrama Božjim u ruci."},{"v":3,"t":"Pjevaju pjesmu Mojsija, sluge Božjega, i pjesmu Jaganjčevu: “Velika su i čudesna djela tvoja, Gospodine, Bože, Svevladaru! Pravedni su i istiniti putovi tvoji, Kralju naroda!"},{"v":4,"t":"Tko da te se ne boji, Gospodine, tko da ne slavi ime tvoje! Ti si jedini svet! I zato svi će narodi doći i klanjati se pred tobom jer se očitovahu pravedna djela tvoja!”"},{"v":5,"t":"Nakon toga vidjeh: otvori se hram Šatora svjedočanstva na nebu!"},{"v":6,"t":"Iziđe sedam anđela sa sedam zala iz hrama; odjeveni bijahu u blistav bijeli lan, oko prsiju opasani zlatnim pojasom."},{"v":7,"t":"Jedno od četiri bića dade sedmorici anđela sedam zlatnih čaša, punih gnjeva Boga koji živi u vijeke vjekova."},{"v":8,"t":"I hram se napuni dimom od Slave Božje i od njegove snage te nitko ne mogaše ući u hram dok se ne navrši sedam zala sedmorice anđela."}]},"16":{"fa":[{"v":1,"t":"و آوازی بلند شنیدم که از میان قدس به آن هفت فرشته می‌گوید که «بروید، هفت پیاله غضب خدا را بر زمین بریزید.»"},{"v":2,"t":"و اولی رفته، پیاله خود را بر زمین ریخت ودمل زشت و بد بر مردمانی که نشان وحش دارندو صورت او را می‌پرستند، بیرون آمد."},{"v":3,"t":"و دومین پیاله خود را به دریا ریخت که آن به خون مثل خون مرده مبدل گشت و هر نفس زنده از چیزهایی که در دریا بود بمرد."},{"v":4,"t":"و سومین پیاله خود را در نهرها و چشمه های آب ریخت و خون شد."},{"v":5,"t":"و فرشته آبها را شنیدم که می‌گوید: عادلی تو که هستی و بودی‌ای قدوس، زیرا که چنین حکم کردی،"},{"v":6,"t":"چونکه خون مقدسین و انبیا را ریختند و بدیشان خون دادی که بنوشند زیرا که مستحقند.»"},{"v":7,"t":"و شنیدم که مذبح می‌گوید: «ای خداوند، خدای قادرمطلق، داوریهای تو حق و عدل است.»"},{"v":8,"t":"و چهارمین، پیاله خود را بر آفتاب ریخت؛ وبه آن داده شد که مردم را به آتش بسوزاند."},{"v":9,"t":"ومردم به حرارت شدید سوخته شدند و به اسم آن خدا که بر این بلایا قدرت دارد، کفر گفتند و توبه نکردند تا او را تمجید نمایند."},{"v":10,"t":"و پنجمین، پیاله خود را بر تخت وحش ریخت و مملکت او تاریک گشت و زبانهای خودرا از درد می‌گزیدند،"},{"v":11,"t":"و به خدای آسمان به‌سبب دردها و دملهای خود کفر می‌گفتند و ازاعمال خود توبه نکردند."},{"v":12,"t":"و ششمین، پیاله خود را بر نهر عظیم فرات ریخت و آبش خشکید تا راه پادشاهانی که ازمشرق آفتاب می‌آیند، مهیا شود."},{"v":13,"t":"و دیدم که ازدهان اژدها و از دهان وحش و از دهان نبی کاذب، سه روح خبیث چون وزغها بیرون می‌آیند."},{"v":14,"t":"زیرا که آنها ارواح دیوها هستند که معجزات ظاهر می‌سازند و بر پادشاهان تمام ربع مسکون خروج می‌کنند تا ایشان را برای جنگ آن روزعظیم خدای قادر مطلق فراهم آورند."},{"v":15,"t":"«اینک چون دزد می‌آیم! خوشابحال کسی‌که بیدار شده، رخت خود را نگاه دارد، مباداعریان راه رود و رسوایی او را ببینند.»"},{"v":16,"t":"و ایشان را به موضعی که آن را در عبرانی حارمجدون می‌خوانند، فراهم آوردند."},{"v":17,"t":"و هفتمین، پیاله خود را بر هوا ریخت وآوازی بلند از میان قدس آسمان از تخت بدرآمده، گفت که «تمام شد.»"},{"v":18,"t":"و برقها و صداها ورعدها حادث گردید و زلزله‌ای عظیم شد آن چنانکه از حین آفرینش انسان بر زمین زلزله‌ای به این شدت و عظمت نشده بود."},{"v":19,"t":"و شهر بزرگ به سه قسم منقسم گشت و بلدان امت‌ها خراب شدو بابل بزرگ در حضور خدا بیاد آمد تا پیاله خمرغضب آلود خشم خود را بدو دهد."},{"v":20,"t":"و هرجزیره گریخت و کوهها نایاب گشت،"},{"v":21,"t":"و تگرگ بزرگ که گویا به وزن یک من بود، از آسمان برمردم بارید و مردم به‌سبب صدمه تگرگ، خدا راکفر گفتند زیرا که صدمه‌اش بینهایت سخت بود."}],"en":[{"v":1,"t":"I heard a loud voice out of the temple, saying to the seven angels, “Go and pour out the seven bowls of the wrath of God on the earth!”"},{"v":2,"t":"The first went, and poured out his bowl into the earth, and it became a harmful and painful sore on the people who had the mark of the beast, and who worshiped his image."},{"v":3,"t":"The second angel poured out his bowl into the sea, and it became blood as of a dead man. Every living thing in the sea died."},{"v":4,"t":"The third poured out his bowl into the rivers and springs of water, and they became blood."},{"v":5,"t":"I heard the angel of the waters saying, “You are righteous, who are and who were, O Holy One, because you have judged these things."},{"v":6,"t":"For they poured out the blood of saints and prophets, and you have given them blood to drink. They deserve this.”"},{"v":7,"t":"I heard the altar saying, “Yes, Lord God, the Almighty, true and righteous are your judgments.”"},{"v":8,"t":"The fourth poured out his bowl on the sun, and it was given to him to scorch men with fire."},{"v":9,"t":"People were scorched with great heat, and people blasphemed the name of God who has the power over these plagues. They didn’t repent and give him glory."},{"v":10,"t":"The fifth poured out his bowl on the throne of the beast, and his kingdom was darkened. They gnawed their tongues because of the pain,"},{"v":11,"t":"and they blasphemed the God of heaven because of their pains and their sores. They still didn’t repent of their works."},{"v":12,"t":"The sixth poured out his bowl on the great river, the Euphrates. Its water was dried up, that the way might be prepared for the kings that come from the sunrise."},{"v":13,"t":"I saw coming out of the mouth of the dragon, and out of the mouth of the beast, and out of the mouth of the false prophet, three unclean spirits, something like frogs;"},{"v":14,"t":"for they are spirits of demons, performing signs, which go out to the kings of the whole inhabited earth, to gather them together for the war of that great day of God the Almighty."},{"v":15,"t":"“Behold, I come like a thief. Blessed is he who watches, and keeps his clothes, so that he doesn’t walk naked, and they see his shame.”"},{"v":16,"t":"He gathered them together into the place which is called in Hebrew, “Harmagedon”."},{"v":17,"t":"The seventh poured out his bowl into the air. A loud voice came out of the temple of heaven, from the throne, saying, “It is done!”"},{"v":18,"t":"There were lightnings, sounds, and thunders; and there was a great earthquake such as has not happened since there were men on the earth—so great an earthquake and so mighty."},{"v":19,"t":"The great city was divided into three parts, and the cities of the nations fell. Babylon the great was remembered in the sight of God, to give to her the cup of the wine of the fierceness of his wrath."},{"v":20,"t":"Every island fled away, and the mountains were not found."},{"v":21,"t":"Great hailstones, about the weight of a talent, came down out of the sky on people. People blasphemed God because of the plague of the hail, for this plague was exceedingly severe."}],"hr":[{"v":1,"t":"I začujem iz hrama jak glas koji viknu sedmorici anđela: “Hajdete, izlijte sedam čaša gnjeva Božjega na zemlju!”"},{"v":2,"t":"Ode prvi i izli svoju čašu na zemlju. I pojavi se čir, koban i bolan, na ljudima što nose žig Zvijerin i klanjaju se kipu njezinu."},{"v":3,"t":"Drugi izli svoju čašu na more. I ono posta krv kao krv mrtvačeva te izginu sve živo u moru."},{"v":4,"t":"Treći izli svoju čašu na rijeke i izvore voda. I postadoše krv."},{"v":5,"t":"I začujem anđela voda gdje govori: “Pravedan si, Ti koji jesi i koji bijaše, Sveti, što si tako dosudio!"},{"v":6,"t":"Oni su prolili krv svetih i proroka i stoga ih krvlju napajaš! Zavrijedili su!”"},{"v":7,"t":"I začujem žrtvenik kako govori: “Da, Gospode, Bože, Svevladaru! Istiniti su i pravedni sudovi tvoji!”"},{"v":8,"t":"Četvrti izli svoju čašu na sunce. I suncu je dano da pali ljude ognjem."},{"v":9,"t":"I silna je žega palila ljude te su hulili ime Boga koji ima vlast nad tim zlima, ali se ne obratiše da mu slavu dadu."},{"v":10,"t":"Peti izli svoju čašu na prijestolje Zvijeri. I kraljevstvo joj prekriše tmine. Ljudi su grizli jezike od muke"},{"v":11,"t":"i hulili Boga nebeskoga zbog muka i čireva, ali se ne obratiše od djela svojih."},{"v":12,"t":"Šesti izli svoju čašu na Eufrat, rijeku veliku. I presahnu voda te načini prolaz kraljima s istoka sunčeva."},{"v":13,"t":"I vidjeh: iz usta Zmajevih i iz usta Zvijerinih i iz usta Lažnoga proroka izlaze tri duha nečista, kao žabe."},{"v":14,"t":"To su dusi zloduha što čine znamenja, a pođoše sabrati kraljeve svega svijeta na rat za Dan veliki Boga Svevladara."},{"v":15,"t":"Evo dolazim kao tat! Blažen onaj koji bdije i čuva haljine svoje da ne ide gol te mu se ne vidi sramota!"},{"v":16,"t":"I skupiše ih na mjesto koje se hebrejski zove Harmagedon."},{"v":17,"t":"I sedmi izli svoju čašu na zrak. Uto iz hrama, s prijestolja, iziđe jak glas i viknu: “Svršeno je!”"},{"v":18,"t":"I udariše munje i glasovi i gromovi i nasta potres velik, kakva ne bijaše otkako je ljudi - tako bijaše silan potres taj."},{"v":19,"t":"I prasnu natroje grad veliki i gradovi naroda padoše. Spomenu se Bog Babilona velikoga da mu dade piti iz čaše vina gnjevne srdžbe Božje."},{"v":20,"t":"I pobjegoše svi otoci, iščezoše gore,"},{"v":21,"t":"a iz neba se spusti na ljude tuča velika, poput talenta. Ljudi su hulili Boga zbog zla tuče jer zlo njezino bijaše silno veliko."}]},"17":{"fa":[{"v":1,"t":"و یکی از آن هفت فرشته‌ای که هفت پیاله را داشتند، آمد و به من خطاب کرده، گفت: «بیا تا قضای آن فاحشه بزرگ را که برآبهای بسیار نشسته است به تو نشان دهم،"},{"v":2,"t":"که پادشاهان جهان با او زنا کردند و ساکنان زمین، ازخمر زنای او مست شدند.»"},{"v":3,"t":"پس مرا در روح به بیابان برد و زنی را دیدم بر وحش قرمزی سوارشده که از نامهای کفر پر بود و هفت سر و ده شاخ داشت."},{"v":4,"t":"و آن زن، به ارغوانی و قرمز ملبس بود وبه طلا و جواهر و مروارید مزین و پیاله‌ای زرین به‌دست خود پر از خبائث و نجاسات زنای خودداشت."},{"v":5,"t":"و بر پیشانی‌اش این اسم مرقوم بود: «سرو بابل عظیم و مادر فواحش و خبائث دنیا.»"},{"v":6,"t":"وآن زن را دیدم، مست از خون مقدسین و از خون شهدای عیسی و از دیدن او بی‌نهایت تعجب نمودم."},{"v":7,"t":"و فرشته مرا گفت: «چرا متعجب شدی؟ من سر زن و آن وحش را که هفت سر و ده شاخ دارد که حامل اوست، به تو بیان می‌نمایم."},{"v":8,"t":"آن وحش که دیدی، بود و نیست و از هاویه خواهدبرآمد و به هلاکت خواهد رفت؛ و ساکنان زمین، جز آنانی که نامهای ایشان از بنای عالم در دفترحیات مرقوم است، در حیرت خواهند افتاد ازدیدن آن وحش که بود و نیست و ظاهر خواهدشد."},{"v":9,"t":"«اینجاست ذهنی که حکمت دارد. این هفت سر، هفت کوه می‌باشد که زن بر آنها نشسته است؛"},{"v":10,"t":"و هفت پادشاه هستند که پنج افتاده‌اند و یکی هست و دیگری هنوز نیامده است و چون آیدمی باید اندکی بماند."},{"v":11,"t":"و آن وحش که بود ونیست، هشتمین است و از آن هفت است و به هلاکت می‌رود."},{"v":12,"t":"و آن ده شاخ که دیدی، ده پادشاه هستند که هنوز سلطنت نیافته‌اند بلکه یک ساعت با وحش چون پادشاهان قدرت می‌یابند."},{"v":13,"t":"اینها یک رای دارند و قوت و قدرت خود را به وحش می‌دهند."},{"v":14,"t":"ایشان با بره جنگ خواهندنمود و بره بر ایشان غالب خواهد آمد، زیرا که اورب‌الارباب و پادشاه پادشاهان است و آنانی نیز که با وی هستند که خوانده شده و برگزیده وامینند.»"},{"v":15,"t":"و مرا می‌گوید: «آبهایی که دیدی، آنجایی که فاحشه نشسته است، قومها و جماعتها وامت‌ها و زبانها می‌باشد."},{"v":16,"t":"و اما ده شاخ که دیدی و وحش، اینها فاحشه را دشمن خواهند داشت واو را بینوا و عریان خواهند نمود و گوشتش راخواهند خورد و او را به آتش خواهند سوزانید،"},{"v":17,"t":"زیرا خدا در دل ایشان نهاده است که اراده او رابه‌جا آرند و یک رای شده، سلطنت خود را به وحش بدهند تا کلام خدا تمام شود."},{"v":18,"t":"و زنی که دیدی، آن شهر عظیم است که بر پادشاهان جهان سلطنت می‌کند.»"}],"en":[{"v":1,"t":"One of the seven angels who had the seven bowls came and spoke with me, saying, “Come here. I will show you the judgment of the great prostitute who sits on many waters,"},{"v":2,"t":"with whom the kings of the earth committed sexual immorality. Those who dwell in the earth were made drunken with the wine of her sexual immorality.”"},{"v":3,"t":"He carried me away in the Spirit into a wilderness. I saw a woman sitting on a scarlet-colored beast, full of blasphemous names, having seven heads and ten horns."},{"v":4,"t":"The woman was dressed in purple and scarlet, and decked with gold and precious stones and pearls, having in her hand a golden cup full of abominations and the impurities of the sexual immorality of the earth."},{"v":5,"t":"And on her forehead a name was written, “MYSTERY, BABYLON THE GREAT, THE MOTHER OF THE PROSTITUTES AND OF THE ABOMINATIONS OF THE EARTH.”"},{"v":6,"t":"I saw the woman drunken with the blood of the saints and with the blood of the martyrs of Jesus. When I saw her, I wondered with great amazement."},{"v":7,"t":"The angel said to me, “Why do you wonder? I will tell you the mystery of the woman and of the beast that carries her, which has the seven heads and the ten horns."},{"v":8,"t":"The beast that you saw was, and is not; and is about to come up out of the abyss and to go into destruction. Those who dwell on the earth and whose names have not been written in the book of life from the foundation of the world will marvel when they see that the beast was, and is not, and shall be present."},{"v":9,"t":"Here is the mind that has wisdom. The seven heads are seven mountains on which the woman sits."},{"v":10,"t":"They are seven kings. Five have fallen, the one is, and the other has not yet come. When he comes, he must continue a little while."},{"v":11,"t":"The beast that was, and is not, is himself also an eighth, and is of the seven; and he goes to destruction."},{"v":12,"t":"The ten horns that you saw are ten kings who have received no kingdom as yet, but they receive authority as kings with the beast for one hour."},{"v":13,"t":"These have one mind, and they give their power and authority to the beast."},{"v":14,"t":"These will war against the Lamb, and the Lamb will overcome them, for he is Lord of lords and King of kings; and those who are with him are called, chosen, and faithful.”"},{"v":15,"t":"He said to me, “The waters which you saw, where the prostitute sits, are peoples, multitudes, nations, and languages."},{"v":16,"t":"The ten horns which you saw, they and the beast will hate the prostitute, will make her desolate, will strip her naked, will eat her flesh, and will burn her utterly with fire."},{"v":17,"t":"For God has put in their hearts to do what he has in mind, to be of one mind, and to give their kingdom to the beast, until the words of God should be accomplished."},{"v":18,"t":"The woman whom you saw is the great city which reigns over the kings of the earth.”"}],"hr":[{"v":1,"t":"I dođe jedan od sedam anđela što nose sedam čaša i prozbori mi: “Dođi pokazat ću ti sud nad Bludnicom velikom što sjedi nad vodama velikim,"},{"v":2,"t":"s kojom su bludničili kraljevi zemlje i pozemljari se opiše vinom bluda njezina.”"},{"v":3,"t":"I odnese me u duhu u pustinju. Tu vidjeh Ženu koja sjede na skrletnu Zvijer, punu bogohulnih imena, sa sedam glava i deset rogova."},{"v":4,"t":"Žena bijaše odjevena u grimiz i skrlet, sva u zlatu, dragom kamenju i biserju. U ruci joj zlatna čaša puna gnusobe i nečisti bluda njezina."},{"v":5,"t":"Na čelo joj napisano ime - tajna: “Babilon veliki, mati bludnica i gnusoba zemljinih.”"},{"v":6,"t":"I vidjeh: Žena je pijana od krvi svetih i od krvi svjedoka Isusovih. Kad je vidjeh, čudom se silnim začudih."},{"v":7,"t":"Nato će mi anđeo: “Što se čudiš? Ja ću ti kazati tajnu te žene i Zvijeri koja je nosi, Zvijeri sa sedam glava i deset rogova.”"},{"v":8,"t":"“Zvijer koju vidje bijaše i više nije; zamalo izlazi iz Bezdana i ide u propast. I zapanjit će se pozemljari - oni kojima ime, od postanka svijeta, nije zapisano u knjigu života - kad vide da Zvijer bijaše i više nije, a opet je tu."},{"v":9,"t":"Tu se hoće mudre pameti! Sedam glava sedam je bregova na kojima žena sjedi. A i sedam kraljeva:"},{"v":10,"t":"pet ih već pade, jedan jest, a jedan još ne dođe: kada dođe, ostati mu je zamalo."},{"v":11,"t":"I Zvijer koja bijaše i više nije, osma je, a iz broja je njih sedmero, i ide u propast."},{"v":12,"t":"Deset rogova što ih vidje deset je kraljeva; oni još ne primiše kraljevstva, ali će - samo za jedan sat - primiti vlast kao kraljevi zajedno sa Zvijeri."},{"v":13,"t":"Jedne su misli: svu svoju silu i vlast predati Zvijeri."},{"v":14,"t":"Ratovat će protiv Jaganjca, ali će ih pobijediti Jaganjac - i njegovi pozvanici, izabranici, vjernici - jer on je Gospodar gospodara i Kralj kraljeva.”"},{"v":15,"t":"I reče mi anđeo: “Vode što ih vidje, na kojima Bludnica sjedi, to su puci i mnoštva i narodi i jezici."},{"v":16,"t":"I onih deset rogova što ih vidje i Zvijer - oni će zamrziti Bludnicu, opustošiti je i ogoliti, najesti se mesa njezina i ognjem je spaliti."},{"v":17,"t":"Jer Bog im u srce stavi izvršiti naum njegov: da jednodušno predadu kraljevstvo svoje Zvijeri dok se ne ispune riječi Božje."},{"v":18,"t":"Žena koju vidje grad je veliki što kraljuje nad kraljevima zemaljskim.”"}]},"18":{"fa":[{"v":1,"t":"بعد از آن دیدم فرشته‌ای دیگر ازآسمان نازل شد که قدرت عظیم داشت و زمین به جلال او منور شد."},{"v":2,"t":"و به آواز زورآورندا کرده، گفت: «منهدم شد، منهدم شد بابل عظیم! و او مسکن دیوها و ملاذ هر روح خبیث وملاذ هر مرغ ناپاک و مکروه گردیده است."},{"v":3,"t":"زیراکه از خمر غضب آلود زنای او همه امت هانوشیده‌اند و پادشاهان جهان با وی زنا کرده‌اند وتجار جهان از کثرت عیاشی او دولتمندگردیده‌اند.»"},{"v":4,"t":"و صدایی دیگر از آسمان شنیدم که می‌گفت: «ای قوم من از میان او بیرون آیید، مبادادر گناهانش شریک شده، از بلاهایش بهره‌مندشوید."},{"v":5,"t":"زیرا گناهانش تا به فلک رسیده و خدا ظلمهایش را به یاد آورده است."},{"v":6,"t":"بدو رد کنیدآنچه را که او داده است و بحسب کارهایش دوچندان بدو جزا دهید و در‌پیاله‌ای که او آمیخته است، او را دو چندان بیامیزید."},{"v":7,"t":"به اندازه‌ای که خویشتن را تمجید کرد و عیاشی نمود، به آنقدرعذاب و ماتم بدو دهید، زیرا که در دل خودمی گوید: به مقام ملکه نشسته‌ام و بیوه نیستم وماتم هرگز نخواهم دید."},{"v":8,"t":"لهذا بلایای او از مرگ وماتم و قحط در یک روز خواهد آمد و به آتش سوخته خواهد شد، زیرا که زورآور است، خداوند خدایی که بر او داوری می‌کند."},{"v":9,"t":"آنگاه پادشاهان دنیا که با او زنا و عیاشی نمودند، چون دود سوختن او را بینند، گریه و ماتم خواهند کرد،"},{"v":10,"t":"و از خوف عذابش دور ایستاده، خواهند گفت: وای وای، ای شهر عظیم، ای بابل، بلده زورآورزیرا که در یک ساعت عقوبت تو آمد."},{"v":11,"t":"«و تجار جهان برای او گریه و ماتم خواهندنمود، زیرا که از این پس بضاعت ایشان را کسی نمی خرد."},{"v":12,"t":"بضاعت طلا و نقره و جواهر ومروارید و کتان نازک و ارغوانی و ابریشم و قرمز وعود قماری و هر ظرف عاج و ظروف چوب گرانبها و مس و آهن و مرمر،"},{"v":13,"t":"و دارچینی وحماما و خوشبوی‌ها و مر و کندر و شراب وروغن و آرد میده و گندم و رمه‌ها و گله‌ها و اسبان و ارابه‌ها و اجساد و نفوس مردم."},{"v":14,"t":"و حاصل شهوت نفس تو از تو گم شد و هر چیز فربه وروشن از تو نابود گردید و دیگر آنها را نخواهی یافت."},{"v":15,"t":"و تاجران این چیزها که از وی دولتمند شده‌اند، از ترس عذابش دور ایستاده، گریان وماتم‌کنان"},{"v":16,"t":"خواهند گفت: وای، وای، ای شهرعظیم که به کتان و ارغوانی و قرمز ملبس می‌بودی و به طلا و جواهر و مروارید مزین، زیرا در یک ساعت اینقدر دولت عظیم خراب شد."},{"v":17,"t":"و هرناخدا و کل جماعتی که بر کشتیها می‌باشند وملاحان و هر‌که شغل دریا می‌کند دور ایستاده،"},{"v":18,"t":"چون دود سوختن آن را دیدند، فریادکنان گفتند: کدام شهر است مثل این شهر بزرگ!"},{"v":19,"t":"وخاک بر سر خود ریخته، گریان و ماتم‌کنان فریادبرآورده، می‌گفتند: «وای، وای بر آن شهر عظیم که از آن هر‌که در دریا صاحب کشتی بود، ازنفایس او دولتمند گردید که در یک ساعت ویران گشت."},{"v":20,"t":"«پس‌ای آسمان و مقدسان و رسولان و انبیاشادی کنید زیرا خدا انتقام شما را از او کشیده است.»"},{"v":21,"t":"و یک فرشته زورآور سنگی چون سنگ آسیای بزرگ گرفته، به دریا انداخت و گفت: «چنین به یک صدمه، شهر بابل منهدم خواهدگردید و دیگر هرگز یافت نخواهد شد."},{"v":22,"t":"وصوت بربطزنان و مغنیان و نی‌زنان و کرنانوازان بعد از این در تو شنیده نخواهد شد و هیچ صنعتگر از هر صناعتی در تو دیگر پیدا نخواهدشد و باز صدای آسیا در تو شنیده نخواهدگردید،"},{"v":23,"t":"و نور چراغ در تو دیگر نخواهد تابید وآواز عروس و داماد باز در تو شنیده نخواهدگشت زیرا که تجار تو اکابر جهان بودند و از جادوگری تو جمیع امت‌ها گمراه شدند."},{"v":24,"t":"و درآن، خون انبیا و مقدسین و تمام مقتولان روی زمین یافت شد.»"}],"en":[{"v":1,"t":"After these things, I saw another angel coming down out of the sky, having great authority. The earth was illuminated with his glory."},{"v":2,"t":"He cried with a mighty voice, saying, “Fallen, fallen is Babylon the great, and she has become a habitation of demons, a prison of every unclean spirit, and a prison of every unclean and hated bird!"},{"v":3,"t":"For all the nations have drunk of the wine of the wrath of her sexual immorality, the kings of the earth committed sexual immorality with her, and the merchants of the earth grew rich from the abundance of her luxury.”"},{"v":4,"t":"I heard another voice from heaven, saying, “Come out of her, my people, that you have no participation in her sins, and that you don’t receive of her plagues,"},{"v":5,"t":"for her sins have reached to the sky, and God has remembered her iniquities."},{"v":6,"t":"Return to her just as she returned, and repay her double as she did, and according to her works. In the cup which she mixed, mix to her double."},{"v":7,"t":"However much she glorified herself and grew wanton, so much give her of torment and mourning. For she says in her heart, ‘I sit a queen, and am no widow, and will in no way see mourning.’"},{"v":8,"t":"Therefore in one day her plagues will come: death, mourning, and famine; and she will be utterly burned with fire, for the Lord God who has judged her is strong."},{"v":9,"t":"The kings of the earth who committed sexual immorality and lived wantonly with her will weep and wail over her, when they look at the smoke of her burning,"},{"v":10,"t":"standing far away for the fear of her torment, saying, ‘Woe, woe, the great city, Babylon, the strong city! For your judgment has come in one hour.’"},{"v":11,"t":"The merchants of the earth weep and mourn over her, for no one buys their merchandise any more:"},{"v":12,"t":"merchandise of gold, silver, precious stones, pearls, fine linen, purple, silk, scarlet, all expensive wood, every vessel of ivory, every vessel made of most precious wood, and of brass, and iron, and marble;"},{"v":13,"t":"and cinnamon, incense, perfume, frankincense, wine, olive oil, fine flour, wheat, cattle, sheep, horses, chariots, and people’s bodies and souls."},{"v":14,"t":"The fruits which your soul lusted after have been lost to you. All things that were dainty and sumptuous have perished from you, and you will find them no more at all."},{"v":15,"t":"The merchants of these things, who were made rich by her, will stand far away for the fear of her torment, weeping and mourning,"},{"v":16,"t":"saying, ‘Woe, woe, the great city, she who was dressed in fine linen, purple, and scarlet, and decked with gold and precious stones and pearls!"},{"v":17,"t":"For in an hour such great riches are made desolate.’ Every ship master, and everyone who sails anywhere, and mariners, and as many as gain their living by sea, stood far away,"},{"v":18,"t":"and cried out as they looked at the smoke of her burning, saying, ‘What is like the great city?’"},{"v":19,"t":"They cast dust on their heads, and cried, weeping and mourning, saying, ‘Woe, woe, the great city, in which all who had their ships in the sea were made rich by reason of her great wealth!’ For she is made desolate in one hour."},{"v":20,"t":"“Rejoice over her, O heaven, you saints, apostles, and prophets, for God has judged your judgment on her.”"},{"v":21,"t":"A mighty angel took up a stone like a great millstone and cast it into the sea, saying, “Thus with violence will Babylon, the great city, be thrown down, and will be found no more at all."},{"v":22,"t":"The voice of harpists, minstrels, flute players, and trumpeters will be heard no more at all in you. No craftsman of whatever craft will be found any more at all in you. The sound of a mill will be heard no more at all in you."},{"v":23,"t":"The light of a lamp will shine no more at all in you. The voice of the bridegroom and of the bride will be heard no more at all in you, for your merchants were the princes of the earth; for with your sorcery all the nations were deceived."},{"v":24,"t":"In her was found the blood of prophets and of saints, and of all who have been slain on the earth.”"}],"hr":[{"v":1,"t":"Nakon toga vidjeh: jedan drugi anđeo silazi s neba s moći velikom! Sva se zemlja zasvijetlila od njegova sjaja."},{"v":2,"t":"On povika iza glasa: “Pade, pade Babilon veliki - Bludnica - i postade prebivalištem zloduha, nastambom svih duhova nečistih, nastambom svih ptica nečistih mrskih"},{"v":3,"t":"jer se gnjevnim vinom bluda njezina opiše narodi; s njom su bludničili svi kraljevi zemaljski, a trgovci se zemaljski obogatiše od silna raskošja njezina.”"},{"v":4,"t":"Začujem i drugi glas s neba: “Iziđite iz nje, narode moj, da vas ne zadese zla njezina te ne budete suzajedničari grijeha njezinih!"},{"v":5,"t":"Jer njezini grijesi do neba dopriješe i spomenu se Bog zločina njezinih."},{"v":6,"t":"Vratite joj milo za drago, naplatite joj dvostruko po djelima! U čašu u koju je ona natakala natočite dvostruko!"},{"v":7,"t":"Koliko se razmetala sjajem i raskoši, toliko joj zadajte muka i jada! Jer u srcu je svome govorila: 'Na prijestolju sjedim kao kraljica i nikad neću obudovjeti, jad me nikada zadesiti neće!'"},{"v":8,"t":"Stoga u isti će je dan zla zadesiti: smrt i jad i glad te će sva u ognju biti spaljena. Jer silan je Gospod, Bog, Sudac njezin!”"},{"v":9,"t":"I plakat će i naricati za njom kraljevi zemlje što su s njome bludničili i raskošno živjeli kad gledali budu dim požara njezina."},{"v":10,"t":"Prestrašeni mukama njezinim, izadaleka će stajati i naricati: “Jao, jao, grade veliki, Babilone, grade silni! Kako li te u tren oka stiže osuda!”"},{"v":11,"t":"I trgovci zemaljski plaču nad njom i tuguju jer im trga nitko više ne kupuje:"},{"v":12,"t":"ni zlata, ni srebra, ni dragoga kamenja, ni biserja, ni tanana lana, ni grimiza, ni svile, ni skrleta: nit ikakva mirisava drveta, nit ikakva predmeta od slonove kosti, nit ikakva predmeta od skupocjena drveta, nit od mjedi, nit od željeza, nit od mramora;"},{"v":13,"t":"ni cimeta, ni balzama, ni miomirisa, ni pomasti, ni tamjana, ni vina, ni ulja, ni bijeloga brašna, ni pšenice; ni goveda, ni ovaca, ni konja, ni kočija, ni roblja nit ikoje žive duše."},{"v":14,"t":"“Voće za kojim ti duša žudjela pobježe od tebe, sav raskoš i sjaj propade ti - ne, nema ga više!”"},{"v":15,"t":"Trgovci što svim tim trgovahu, što ih ona obogati, izdaleka će stajati, prestrašeni mukama njezinim, plakat će i tugovati:"},{"v":16,"t":"“Jao, jao, grade veliki, odjeveni nekoć u lan tanan i grimiz i skrlet, nakićeni zlatom i dragim kamenjem i biserjem!"},{"v":17,"t":"U tren oka opustje toliko bogatstvo!” I svi kormilari i putnici, svi mornari i moreplovci izdaleka stoje"},{"v":18,"t":"i, gledajući dim njezina požara, zapomažu: “Koji li je grad sličan gradu ovom velikom?”"},{"v":19,"t":"I posuše glavu pepelom te plačući i tugujući viknuše: “Jao, jao, grada li velikoga! Dragocjenostima se njegovim obogatiše svi posjednici morskih brodova, a evo - u tren oka opustje!”"},{"v":20,"t":"Veseli se nad njom, nebo, i svi sveti i apostoli i proroci jer Bog osudivši nju, vama pravo dosudi!"},{"v":21,"t":"I jedan snažan anđeo uze kamen, velik poput mlinskoga kamena, i baci ga u more govoreći: “Tako će silovito biti strovaljen Babilon, grad veliki, i nikada ga više biti neće!”"},{"v":22,"t":"“Glas citraša i pjevača i svirača i trubljača u tebi se više neće čuti! Obrtnik vješt kojem god umijeću u tebi se više neće naći! Klopot žrvnja u tebi se više neće čuti!"},{"v":23,"t":"Svjetlost svjetiljke u tebi više neće sjati! Glas zaručnika i zaručnice u tebi se više neće čuti! Jer trgovci tvoji bijahu velikaši zemlje i čaranja tvoja zavedoše sve narode;"},{"v":24,"t":"i u tebi se našla krv proroka i svetaca i svih zaklanih na zemlji.”"}]},"19":{"fa":[{"v":1,"t":"و بعد از آن شنیدم چون آوازی بلند ازگروهی کثیر در آسمان که می‌گفتند: «هللویاه! نجات و جلال و اکرام و قوت از آن خدای ما است،"},{"v":2,"t":"زیرا که احکام او راست و عدل است، چونکه داوری نمود بر فاحشه بزرگ که جهان را به زنای خود فاسد می‌گردانید و انتقام خون بندگان خود را از دست او کشید.»"},{"v":3,"t":"و بار دیگر گفتند: «هللویاه، و دودش تاابدالاباد بالا می‌رود!»"},{"v":4,"t":"و آن بیست و چهار پیر و چهار حیوان به روی درافتاده، خدایی را که بر تخت نشسته است سجده نمودند و گفتند: «آمین، هللویاه!»"},{"v":5,"t":"و آوازی از تخت بیرون آمده، گفت: «حمدنمایید خدای ما را‌ای تمامی بندگان او وترسندگان او چه کبیر و چه صغیر.»"},{"v":6,"t":"و شنیدم چون آواز جمعی کثیر و چون آوازآبهای فراوان و چون آواز رعدهای شدید که می‌گفتند: «هللویاه، زیرا خداوند خدای ما قادرمطلق، سلطنت گرفته است."},{"v":7,"t":"شادی و وجدنماییم و او را تمجید کنیم زیرا که نکاح بره رسیده است و عروس او خود را حاضر ساخته است."},{"v":8,"t":"وبه او داده شد که به کتان، پاک و روشن خود رابپوشاند، زیرا که آن کتان عدالتهای مقدسین است.»"},{"v":9,"t":"و مرا گفت: «بنویس: خوشابحال آنانی که به بزم نکاح بره دعوت شده‌اند.» و نیز مرا گفت که «این است کلام راست خدا.»"},{"v":10,"t":"و نزد پایهایش افتادم تا او را سجده کنم. اوبه من گفت: «زنهار چنین نکنی زیرا که من با توهمخدمت هستم و با برادرانت که شهادت عیسی را دارند. خدا را سجده کن زیرا که شهادت عیسی روح نبوت است.»"},{"v":11,"t":"و دیدم آسمان را گشوده و ناگاه اسبی سفیدکه سوارش امین و حق نام دارد و به عدل داوری وجنگ می‌نماید،"},{"v":12,"t":"و چشمانش چون شعله آتش و بر سرش افسرهای بسیار و اسمی مرقوم داردکه جز خودش هیچ‌کس آن را نمی داند."},{"v":13,"t":"وجامه‌ای خون آلود دربر دارد و نام او را «کلمه خدا» می‌خوانند."},{"v":14,"t":"و لشکرهایی که درآسمانند، بر اسبهای سفید و به کتان سفید و پاک ملبس از عقب او می‌آمدند."},{"v":15,"t":"و از دهانش شمشیری تیز بیرون می‌آید تا به آن امت‌ها را بزندو آنها را به عصای آهنین حکمرانی خواهد نمودو او چرخشت خمر غضب و خشم خدای قادرمطلق را زیر پای خود می‌افشرد."},{"v":16,"t":"و بر لباس وران او نامی مرقوم است یعنی «پادشاه پادشاهان ورب‌الارباب»."},{"v":17,"t":"و دیدم فرشته‌ای را در آفتاب ایستاده که به آواز بلند تمامی مرغانی را که در آسمان پروازمی کنند، ندا کرده، می‌گوید: «بیایید و بجهت ضیافت عظیم خدا فراهم شوید."},{"v":18,"t":"تا بخورید گوشت پادشاهان و گوشت سپه سالاران و گوشت جباران و گوشت اسبها و سواران آنها و گوشت همگان را، چه آزاد و چه غلام، چه صغیر و چه کبیر.»"},{"v":19,"t":"و دیدم وحش و پادشاهان زمین ولشکرهای ایشان را که جمع شده بودند تا بااسب‌سوار و لشکر او جنگ کنند."},{"v":20,"t":"و وحش گرفتار شد و نبی کاذب با وی که پیش او معجزات ظاهر می‌کرد تا به آنها آنانی را که نشان وحش رادارند و صورت او را می‌پرستند، گمراه کند. این هر دو، زنده به دریاچه آتش افروخته شده به کبریت انداخته شدند."},{"v":21,"t":"و باقیان به شمشیری که از دهان اسب‌سوار بیرون می‌آمد کشته شدند وتمامی مرغان از گوشت ایشان سیر گردیدند."}],"en":[{"v":1,"t":"After these things I heard something like a loud voice of a great multitude in heaven, saying, “Hallelujah! Salvation, power, and glory belong to our God;"},{"v":2,"t":"for his judgments are true and righteous. For he has judged the great prostitute who corrupted the earth with her sexual immorality, and he has avenged the blood of his servants at her hand.”"},{"v":3,"t":"A second said, “Hallelujah! Her smoke goes up forever and ever.”"},{"v":4,"t":"The twenty-four elders and the four living creatures fell down and worshiped God who sits on the throne, saying, “Amen! Hallelujah!”"},{"v":5,"t":"A voice came from the throne, saying, “Give praise to our God, all you his servants, you who fear him, the small and the great!”"},{"v":6,"t":"I heard something like the voice of a great multitude, and like the voice of many waters, and like the voice of mighty thunders, saying, “Hallelujah! For the Lord our God, the Almighty, reigns!"},{"v":7,"t":"Let’s rejoice and be exceedingly glad, and let’s give the glory to him. For the wedding of the Lamb has come, and his wife has made herself ready.”"},{"v":8,"t":"It was given to her that she would array herself in bright, pure, fine linen, for the fine linen is the righteous acts of the saints."},{"v":9,"t":"He said to me, “Write, ‘Blessed are those who are invited to the wedding supper of the Lamb.’” He said to me, “These are true words of God.”"},{"v":10,"t":"I fell down before his feet to worship him. He said to me, “Look! Don’t do it! I am a fellow bondservant with you and with your brothers who hold the testimony of Jesus. Worship God, for the testimony of Jesus is the Spirit of Prophecy.”"},{"v":11,"t":"I saw the heaven opened, and behold, a white horse, and he who sat on it is called Faithful and True. In righteousness he judges and makes war."},{"v":12,"t":"His eyes are a flame of fire, and on his head are many crowns. He has names written and a name written which no one knows but he himself."},{"v":13,"t":"He is clothed in a garment sprinkled with blood. His name is called “The Word of God.”"},{"v":14,"t":"The armies which are in heaven, clothed in white, pure, fine linen, followed him on white horses."},{"v":15,"t":"Out of his mouth proceeds a sharp, double-edged sword that with it he should strike the nations. He will rule them with an iron rod. He treads the wine press of the fierceness of the wrath of God, the Almighty."},{"v":16,"t":"He has on his garment and on his thigh a name written, “KING OF KINGS AND LORD OF LORDS.”"},{"v":17,"t":"I saw an angel standing in the sun. He cried with a loud voice, saying to all the birds that fly in the sky, “Come! Be gathered together to the great supper of God,"},{"v":18,"t":"that you may eat the flesh of kings, the flesh of captains, the flesh of mighty men, and the flesh of horses and of those who sit on them, and the flesh of all men, both free and slave, small and great.”"},{"v":19,"t":"I saw the beast, the kings of the earth, and their armies, gathered together to make war against him who sat on the horse and against his army."},{"v":20,"t":"The beast was taken, and with him the false prophet who worked the signs in his sight, with which he deceived those who had received the mark of the beast and those who worshiped his image. These two were thrown alive into the lake of fire that burns with sulfur."},{"v":21,"t":"The rest were killed with the sword of him who sat on the horse, the sword which came out of his mouth. So all the birds were filled with their flesh."}],"hr":[{"v":1,"t":"Nakon toga začujem kao jak glas silnoga mnoštva na nebu: “Aleluja! Spasenje i slava i moć Bogu našemu!"},{"v":2,"t":"Doista, istiniti su i pravedni sudovi njegovi jer osudi veliku Bludnicu, što pokvari zemlju bludom svojim, i osveti na njoj krv slugu svojih!”"},{"v":3,"t":"I ponove: “Aleluja! Dim njezin suklja u vijeke vjekova!”"},{"v":4,"t":"Nato starješine, njih dvadesetčetvorica, i ona četiri bića padoše ničice i p okloniše se Bogu, koji sjedi na prijestolju, govoreći: “Amen! Aleluja!”"},{"v":5,"t":"I s prijestolja iziđe glas: “Hvalite Boga našega, sve sluge njegove, svi koji se njega bojite, i mali i veliki!”"},{"v":6,"t":"I začuh kao glas silna mnoštva i kao šum voda mnogih i kao prasak gromova silnih: “Aleluja! Zakraljeva Gospod, Bog naš Svevladar!"},{"v":7,"t":"Radujmo se i kličimo i slavu mu dajmo jer dođe svadba Jaganjčeva, opremila se Zaručnica njegova!"},{"v":8,"t":"Dano joj je odjenuti se u lan tanan, blistav i čist!” A lan - pravedna su djela svetih."},{"v":9,"t":"I reče mi: “Piši! Blago onima koji su pozvani na svadbenu gozbu Jaganjčevu!” I reče mi: “Ove su riječi istinite, Božje.”"},{"v":10,"t":"Padoh mu pred noge da mu se poklonim. A on će mi: “Nipošto! Sluga sam kao i ti i braća tvoja koja imaju svjedočanstvo Isusovo. Bogu se pokloni!” Jer svjedočanstvo Isusovo duh je proročki."},{"v":11,"t":"I vidjeh: nebo otvoreno - i gle, konj bijelac, a na nj sjeo On, zvani Vjerni i Istiniti, a sudi i vojuje po pravdi;"},{"v":12,"t":"oči mu plamen ognjeni, na glavi mu mnoge krune; nosi napisano ime kojeg nitko ne zna doli on sam;"},{"v":13,"t":"ogrnut je ogrtačem krvlju natopljenim; ime mu: Riječ Božja."},{"v":14,"t":"Prate ga na bijelcima Vojske nebeske, odjevene u lan tanan, bijel i čist."},{"v":15,"t":"Iz usta mu izlazi oštar mač kojim će posjeći narode. Vladat će njima palicom gvozdenom. On gazi u kaci gnjevne srdžbe Boga Svevladara."},{"v":16,"t":"Na ogrtač, o boku, napisano mu ime: “Kralj kraljeva i Gospodar gospodara.”"},{"v":17,"t":"I vidjeh jednog anđela: stajaše na suncu vičući iza glasa svim pticama što nebom lete: “Ovamo! Skupite se na veliku gozbu Božju"},{"v":18,"t":"da se najedete mesa kraljeva, i mesa vojvoda, i mesa mogućnika, i mesa konja i konjanika njihovih, i mesa svih mogućih ljudi, slobodnjaka i robova, malih i velikih!”"},{"v":19,"t":"I vidjeh: Zvijer i kraljevi zemlje i vojske njihove skupiše se u boj da se zarate s Onim što sjedi na konju i s vojskom njegovom."},{"v":20,"t":"I Zvijer bi uhvaćena, a s njom i Lažni prorok koji je u njenoj nazočnosti činio znamenja i njima zavodio one što su primili žig Zvijeri i klanjali se njezinu kipu. Živi su oboje bačeni u ognjeno jezero što gori sumporom."},{"v":21,"t":"A drugi su posječeni mačem što iziđe iz usta Onoga koji sjedi na konju i sve se ptice nasitiše mesa njihova."}]},"20":{"fa":[{"v":1,"t":"و دیدم فرشته‌ای را که از آسمان نازل می شود و کلید هاویه را دارد و زنجیری بزرگ بر دست وی است."},{"v":2,"t":"و اژدها یعنی مار قدیم را که ابلیس و شیطان می‌باشد، گرفتار کرده، او راتا مدت هزار سال در بند نهاد."},{"v":3,"t":"و او را به هاویه انداخت و در را بر او بسته، مهر کرد تا امت‌ها رادیگر گمراه نکند تا مدت هزار سال به انجام رسد؛ و بعد از آن می‌باید اندکی خلاصی یابد."},{"v":4,"t":"و تختها دیدم و بر آنها نشستند و به ایشان حکومت داده شد و دیدم نفوس آنانی را که بجهت شهادت عیسی و کلام خدا سر بریده شدند و آنانی را که وحش و صورتش را پرستش نکردند و نشان او را بر پیشانی و دست خود نپذیرفتند که زنده شدند و با مسیح هزار سال سلطنت کردند."},{"v":5,"t":"و سایر مردگان زنده نشدند تاهزار سال به اتمام رسید. این است قیامت اول."},{"v":6,"t":"خوشحال و مقدس است کسی‌که از قیامت اول قسمتی دارد. بر اینها موت ثانی تسلط ندارد بلکه کاهنان خدا و مسیح خواهند بود و هزار سال با اوسلطنت خواهند کرد."},{"v":7,"t":"و چون هزار سال به انجام رسد، شیطان اززندان خود خلاصی خواهد یافت"},{"v":8,"t":"تا بیرون رودو امت هایی را که در چهار زاویه جهانند، یعنی جوج و ماجوج را گمراه کند و ایشان را بجهت جنگ فراهم آورد که عدد ایشان چون ریگ دریاست."},{"v":9,"t":"و بر عرصه جهان برآمده، لشکرگاه مقدسین و شهر محبوب را محاصره کردند. پس آتش از جانب خدا از آسمان فرو ریخته، ایشان رابلعید."},{"v":10,"t":"و ابلیس که ایشان را گمراه می‌کند، به دریاچه آتش و کبریت انداخته شد، جایی که وحش و نبی کاذب هستند؛ و ایشان تا ابدالابادشبانه‌روز عذاب خواهند کشید."},{"v":11,"t":"و دیدم تختی بزرگ سفید و کسی را بر آن نشسته که از روی وی آسمان و زمین گریخت وبرای آنها جایی یافت نشد."},{"v":12,"t":"و مردگان را خرد وبزرگ دیدم که پیش تخت ایستاده بودند؛ و دفترهارا گشودند. پس دفتری دیگر گشوده شد که دفترحیات‌است و بر مردگان داوری شد، بحسب اعمال ایشان از آنچه در دفترها مکتوب است."},{"v":13,"t":"و دریا مردگانی را که در آن بودند باز داد؛ و موت و عالم اموات مردگانی را که در آنها بودندباز دادند؛ و هر یکی بحسب اعمالش حکم یافت."},{"v":14,"t":"و موت و عالم اموات به دریاچه آتش انداخته شد. این است موت ثانی، یعنی دریاچه آتش."},{"v":15,"t":"و هر‌که در دفتر حیات مکتوب یافت نشد، به دریاچه آتش افکنده گردید."}],"en":[{"v":1,"t":"I saw an angel coming down out of heaven, having the key of the abyss and a great chain in his hand."},{"v":2,"t":"He seized the dragon, the old serpent, who is the devil and Satan, who deceives the whole inhabited earth, and bound him for a thousand years,"},{"v":3,"t":"and cast him into the abyss, and shut it and sealed it over him, that he should deceive the nations no more until the thousand years were finished. After this, he must be freed for a short time."},{"v":4,"t":"I saw thrones, and they sat on them, and judgment was given to them. I saw the souls of those who had been beheaded for the testimony of Jesus and for the word of God, and such as didn’t worship the beast nor his image, and didn’t receive the mark on their forehead and on their hand. They lived and reigned with Christ for a thousand years."},{"v":5,"t":"The rest of the dead didn’t live until the thousand years were finished. This is the first resurrection."},{"v":6,"t":"Blessed and holy is he who has part in the first resurrection. Over these, the second death has no power, but they will be priests of God and of Christ, and will reign with him one thousand years."},{"v":7,"t":"And after the thousand years, Satan will be released from his prison"},{"v":8,"t":"and he will come out to deceive the nations which are in the four corners of the earth, Gog and Magog, to gather them together to the war, whose number is as the sand of the sea."},{"v":9,"t":"They went up over the width of the earth and surrounded the camp of the saints and the beloved city. Fire came down out of heaven from God and devoured them."},{"v":10,"t":"The devil who deceived them was thrown into the lake of fire and sulfur, where the beast and the false prophet are also. They will be tormented day and night forever and ever."},{"v":11,"t":"I saw a great white throne and him who sat on it, from whose face the earth and the heaven fled away. There was found no place for them."},{"v":12,"t":"I saw the dead, the great and the small, standing before the throne, and they opened books. Another book was opened, which is the book of life. The dead were judged out of the things which were written in the books, according to their works."},{"v":13,"t":"The sea gave up the dead who were in it. Death and Hades gave up the dead who were in them. They were judged, each one according to his works."},{"v":14,"t":"Death and Hades were thrown into the lake of fire. This is the second death, the lake of fire."},{"v":15,"t":"If anyone was not found written in the book of life, he was cast into the lake of fire."}],"hr":[{"v":1,"t":"I vidjeh anđela: siđe s neba s ključima Bezdana i s velikim okovima u ruci."},{"v":2,"t":"Zgrabi Zmaja, Staru zmiju, to jest Ðavla, Sotonu, i okova ga za tisuću godina."},{"v":3,"t":"Baci ga u Bezdan koji nad njim zatvori i zapečati da više ne zavodi narode dok se ne navrši tisuću godina. Nakon toga ima biti odriješen za malo vremena."},{"v":4,"t":"I vidjeh prijestolja - onima što sjedoše na njih dano je suditi - i duše pogubljenih zbog svjedočanstva Isusova i zbog Riječi Božje i sve koji se ne pokloniše Zvijeri ni kipu njezinu te ne primiše žiga na čela svoja ni na ruke. Oni oživješe i zakraljevaše s Kristom tisuću godina."},{"v":5,"t":"Drugi mrtvi ne oživješe dok se ne navrši tisuću godina. To je ono prvo uskrsnuće."},{"v":6,"t":"Blažen i svet onaj tko je dionik toga prvog uskrsnuća! Nad njim druga smrt nema vlasti: oni će biti svećenici Božji i Kristovi i s njime će kraljevati tisuću godina."},{"v":7,"t":"A kad se navrši tisuću godina, Sotona će iz svoga zatvora biti pušten:"},{"v":8,"t":"izići će zavesti narode sa četiri kraja zemlje, Goga i Magoga, i skupiti ih u boj. Bit će ih kao pijeska morskoga."},{"v":9,"t":"Skupiše se na prostrano polje zemlje i opkoliše tabor svetih i ljubljeni grad. Ali oganj siđe s neba te ih proguta."},{"v":10,"t":"A njihov zavodnik, Ðavao, bačen bi u jezero ognjeno i sumporno, gdje se nalaze i Zvijer i Lažni prorok: ondje će se mučiti danju i noću u vijeke vjekova."},{"v":11,"t":"I vidjeh veliko bijelo prijestolje i Onoga što sjede na nj: pred licem njegovim pobježe zemlja i nebo; ni mjesta im se više ne nađe."},{"v":12,"t":"I vidjeh mrtve, velike i male: stoje pred prijestoljem, a knjige se otvoriše. I otvori se jedna druga knjiga, knjiga života. I mrtvi bijahu suđeni po onome što stoji napisano u knjigama, po djelima svojim."},{"v":13,"t":"More predade svoje mrtvace, a Smrt i Podzemlje svoje: i svaki bi suđen po djelima svojim."},{"v":14,"t":"A Smrt i Podzemlje bili su bačeni u jezero ognjeno. Jezero ognjeno - to je druga smrt:"},{"v":15,"t":"tko se god ne nađe zapisan u knjizi života, bio je bačen u jezero ognjeno."}]},"21":{"fa":[{"v":1,"t":"و دیدم آسمانی جدید و زمینی جدید، چونکه آسمان اول و زمین اول درگذشت و دریا دیگر نمی باشد."},{"v":2,"t":"و شهر مقدس اورشلیم جدید را دیدم که از جانب خدا ازآسمان نازل می‌شود، حاضر شده چون عروسی که برای شوهر خود آراسته است."},{"v":3,"t":"و آوازی بلنداز آسمان شنیدم که می‌گفت: «اینک خیمه خدا باآدمیان است و با ایشان ساکن خواهد بود و ایشان قوم های او خواهند بود و خود خدا با ایشان خدای ایشان خواهد بود."},{"v":4,"t":"و خدا هر اشکی ازچشمان ایشان پاک خواهد کرد. و بعد از آن موت نخواهد بود و ماتم و ناله و درد دیگر رو نخواهدنمود زیرا که چیزهای اول درگذشت.»"},{"v":5,"t":"و آن تخت‌نشین گفت: «الحال همه‌چیز را نومی سازم.» و گفت: «بنویس، زیرا که این کلام امین و راست است.»"},{"v":6,"t":"باز مرا گفت: «تمام شد! من الف و یا و ابتدا وانتها هستم. من به هر‌که تشنه باشد، از چشمه آب حیات، مفت خواهم داد."},{"v":7,"t":"و هر‌که غالب آید، وارث همه‌چیز خواهد شد، و او را خدا خواهم بود و او مرا پسر خواهد بود."},{"v":8,"t":"لکن ترسندگان و بی ایمانان و خبیثان و قاتلان و زانیان و جادوگران و بت‌پرستان و جمیع دروغگویان، نصیب ایشان در دریاچه افروخته شده به آتش و کبریت خواهدبود. این است موت ثانی.»"},{"v":9,"t":"و یکی از آن هفت فرشته که هفت پیاله پر ازهفت بلای آخرین را دارند، آمد و مرا مخاطب ساخته، گفت: «بیا تا عروس منکوحه بره را به تونشان دهم.»"},{"v":10,"t":"آنگاه مرا در روح، به کوهی بزرگ بلند برد و شهر مقدس اورشلیم را به من نمود که از آسمان از جانب خدا نازل می‌شود،"},{"v":11,"t":"و جلال خدا را دارد و نورش مانند جواهر گرانبها، چون یشم بلورین."},{"v":12,"t":"و دیواری بزرگ و بلند دارد ودوازده دروازه دارد و بر سر دروازه‌ها دوازده فرشته و اسم‌ها بر ایشان مرقوم است که نامهای دوازده سبط بنی‌اسرائیل باشد."},{"v":13,"t":"از مشرق سه دروازه و از شمال سه دروازه و از جنوب سه دروازه و از مغرب سه دروازه."},{"v":14,"t":"و دیوار شهردوازده اساس دارد و بر آنها دوازده اسم دوازده رسول بره است."},{"v":15,"t":"و آن کس که با من تکلم می‌کرد، نی طلاداشت تا شهر و دروازه هایش و دیوارش رابپیماید."},{"v":16,"t":"و شهر مربع است که طول و عرضش مساوی است و شهر را به آن نی پیموده، دوازده هزار تیر پرتاب یافت و طول و عرض وبلندی‌اش برابر است."},{"v":17,"t":"و دیوارش را صد و چهل و چهارذراع پیمود، موافق ذراع انسان، یعنی فرشته."},{"v":18,"t":"وبنای دیوار آن از یشم بود و شهر از زر خالص چون شیشه مصفی بود."},{"v":19,"t":"و بنیاد دیوار شهر به هر نوع جواهر گرانبها مزین بود که بنیاد اول، یشم و دوم، یاقوت کبود و سوم، عقیق سفید و چهارم، زمرد"},{"v":20,"t":"و پنجم، جزع عقیقی و ششم، عقیق وهفتم، زبرجد و هشتم، زمرد سلقی و نهم، طوپاز ودهم، عقیق اخضر و یازدهم، آسمانجونی ودوازدهم، یاقوت بود."},{"v":21,"t":"و دوازده دروازه، دوازده مروارید بود، هر دروازه از یک مروارید وشارع عام شهر، از زر خالص چون شیشه شفاف."},{"v":22,"t":"و در آن هیچ قدس ندیدم زیرا خداوندخدای قادر مطلق و بره قدس آن است."},{"v":23,"t":"و شهراحتیاج ندارد که آفتاب یا ماه آن را روشنایی دهدزیرا که جلال خدا آن را منور می‌سازد و چراغش بره است."},{"v":24,"t":"و امت‌ها در نورش سالک خواهندبود و پادشاهان جهان، جلال و اکرام خود را به آن خواهند درآورد."},{"v":25,"t":"و دروازه هایش در روز بسته نخواهد بود زیرا که شب در آنجا نخواهد بود."},{"v":26,"t":"و جلال و عزت امت‌ها را به آن داخل خواهندساخت."},{"v":27,"t":"و چیزی ناپاک یا کسی‌که مرتکب عمل زشت یا دروغ شود، هرگز داخل آن نخواهدشد، مگر آنانی که در دفتر حیات بره مکتوبند."}],"en":[{"v":1,"t":"I saw a new heaven and a new earth, for the first heaven and the first earth have passed away, and the sea is no more."},{"v":2,"t":"I saw the holy city, New Jerusalem, coming down out of heaven from God, prepared like a bride adorned for her husband."},{"v":3,"t":"I heard a loud voice out of heaven saying, “Behold, God’s dwelling is with people; and he will dwell with them, and they will be his people, and God himself will be with them as their God."},{"v":4,"t":"He will wipe away every tear from their eyes. Death will be no more; neither will there be mourning, nor crying, nor pain any more. The first things have passed away.”"},{"v":5,"t":"He who sits on the throne said, “Behold, I am making all things new.” He said, “Write, for these words of God are faithful and true.”"},{"v":6,"t":"He said to me, “I am the Alpha and the Omega, the Beginning and the End. I will give freely to him who is thirsty from the spring of the water of life."},{"v":7,"t":"He who overcomes, I will give him these things. I will be his God, and he will be my son."},{"v":8,"t":"But for the cowardly, unbelieving, sinners, abominable, murderers, sexually immoral, sorcerers, idolaters, and all liars, their part is in the lake that burns with fire and sulfur, which is the second death.”"},{"v":9,"t":"One of the seven angels who had the seven bowls which were loaded with the seven last plagues came, and he spoke with me, saying, “Come here. I will show you the bride, the Lamb’s wife.”"},{"v":10,"t":"He carried me away in the Spirit to a great and high mountain, and showed me the holy city, Jerusalem, coming down out of heaven from God,"},{"v":11,"t":"having the glory of God. Her light was like a most precious stone, like a jasper stone, clear as crystal;"},{"v":12,"t":"having a great and high wall with twelve gates, and at the gates twelve angels, and names written on them, which are the names of the twelve tribes of the children of Israel."},{"v":13,"t":"On the east were three gates, and on the north three gates, and on the south three gates, and on the west three gates."},{"v":14,"t":"The wall of the city had twelve foundations, and on them twelve names of the twelve Apostles of the Lamb."},{"v":15,"t":"He who spoke with me had for a measure a golden reed to measure the city, its gates, and its walls."},{"v":16,"t":"The city is square. Its length is as great as its width. He measured the city with the reed: twelve thousand twelve stadia. Its length, width, and height are equal."},{"v":17,"t":"Its wall is one hundred forty-four cubits, by the measure of a man, that is, of an angel."},{"v":18,"t":"The construction of its wall was jasper. The city was pure gold, like pure glass."},{"v":19,"t":"The foundations of the city’s wall were adorned with all kinds of precious stones. The first foundation was jasper, the second sapphire; the third chalcedony, the fourth emerald,"},{"v":20,"t":"the fifth sardonyx, the sixth sardius, the seventh chrysolite, the eighth beryl, the ninth topaz, the tenth chrysoprase, the eleventh jacinth, and the twelfth amethyst."},{"v":21,"t":"The twelve gates were twelve pearls. Each one of the gates was made of one pearl. The street of the city was pure gold, like transparent glass."},{"v":22,"t":"I saw no temple in it, for the Lord God the Almighty and the Lamb are its temple."},{"v":23,"t":"The city has no need for the sun or moon to shine, for the very glory of God illuminated it and its lamp is the Lamb."},{"v":24,"t":"The nations will walk in its light. The kings of the earth bring the glory and honor of the nations into it."},{"v":25,"t":"Its gates will in no way be shut by day (for there will be no night there),"},{"v":26,"t":"and they shall bring the glory and the honor of the nations into it so that they may enter."},{"v":27,"t":"There will in no way enter into it anything profane, or one who causes an abomination or a lie, but only those who are written in the Lamb’s book of life."}],"hr":[{"v":1,"t":"I vidjeh novo nebo i novu zemlju jer - prvo nebo i prva zemlja uminu; ni mora više nema."},{"v":2,"t":"I Sveti grad, novi Jeruzalem, vidjeh: silazi s neba od Boga, opremljen kao zaručnica nakićena za svoga muža."},{"v":3,"t":"I začujem jak glas s prijestolja: “Evo Šatora Božjeg s ljudima! On će prebivati s njima: oni će biti narod njegov, a on će biti Bog s njima."},{"v":4,"t":"I otrt će im svaku suzu s očiju te smrti više neće biti, ni tuge, ni jauka, ni boli više neće biti jer - prijašnje uminu.”"},{"v":5,"t":"Tada Onaj što sjedi na prijestolju reče: “Evo, sve činim novo!” I doda: “Napiši: Ove su riječi vjerne i istinite.”"},{"v":6,"t":"I još mi reče: “Svršeno je! Ja sam Alfa i Omega, Početak i Svršetak! Ja ću žednomu dati s izvora vode života zabadava."},{"v":7,"t":"To će biti baština pobjednikova. I ja ću njemu biti Bog, a on meni sin."},{"v":8,"t":"Kukavicama pak, nevjernima i okaljanima, ubojicama, bludnicima, vračarima i idolopoklonicima i svim lažljivcima udio je u jezeru što gori ognjem i sumporom. To je druga smrt.”"},{"v":9,"t":"I dođe jedan od sedam anđela što imaju sedam čaša punih zala konačnih te progovori sa mnom: “Dođi, pokazat ću ti Zaručnicu, Ženu Jaganjčevu!”"},{"v":10,"t":"I prenese me u duhu na goru veliku, visoku i pokaza mi sveti grad Jeruzalem: silazi s neba od Boga,"},{"v":11,"t":"sav u slavi Božjoj, blistav poput dragoga kamena, kamena slična kristalnom jaspisu;"},{"v":12,"t":"okružen zidinama velikim i visokim, sa dvanaest vrata: na vratima dvanaest anđela i napisana imena dvanaest plemena Izraelovih."},{"v":13,"t":"Od istoka vrata troja, od sjevera vrata troja, od juga vrata troja, od zapada vrata troja."},{"v":14,"t":"Gradske su zidine imale dvanaest temelja, a na njima dvanaest imena dvanaestorice apostola Jaganjčevih."},{"v":15,"t":"Moj subesjednik imaše mjeru, zlatnu trsku, da izmjeri grad, vrata njegova i zidine."},{"v":16,"t":"Grad se stere u četvorini: dužina mu jednaka širini. On izmjeri trskom grad: dvanaest tisuća stadija - dužina mu i širina i visina jednaka."},{"v":17,"t":"Izmjeri i njegove zidine: sto četrdeset i četiri lakta po čovjekovoj mjeri kojom je mjerio anđeo."},{"v":18,"t":"Zidine su gradske sagrađene od jaspisa, a sam grad od čistoga zlata, slična čistu staklu."},{"v":19,"t":"Temelji su gradskih zidina urešeni svakovrsnim dragim kamenjem: prvi je temelj od jaspisa, drugi od safira, treći od kalcedona, četvrti od smaragda,"},{"v":20,"t":"peti od sardoniksa, šesti od sarda, sedmi od krizolita, osmi od berila, deveti od topaza, deseti od krizopraza, jedanaesti od hijacinta, dvanaesti od ametista."},{"v":21,"t":"Dvanaest vrata - dvanaest bisera: svaka od svoga bisera. A gradski trg - čisto zlato, kao prozirno staklo."},{"v":22,"t":"Hrama u gradu ne vidjeh. Ta Gospod, Bog, Svevladar, hram je njegov - i Jaganjac!"},{"v":23,"t":"I gradu ne treba ni sunca ni mjeseca da mu svijetle. Ta Slava ga Božja obasjala i svjetiljka mu Jaganjac!"},{"v":24,"t":"Narodi će hoditi u svjetlosti njegovoj, a kraljevi zemaljski u nj donositi slavu svoju."},{"v":25,"t":"Vrata mu se ne zatvaraju obdan, a noći ondje i nema."},{"v":26,"t":"U nj će se donijeti slava i čast naroda."},{"v":27,"t":"Ali u nj neće unići ništa nečisto i nijedan tko čini gadost i laž, nego samo oni koji su zapisani u Jaganjčevoj knjizi života."}]},"22":{"fa":[{"v":1,"t":"و نهری از آب حیات به من نشان داد که درخشنده بود، مانند بلور و از تخت خدا و بره جاری می‌شود."},{"v":2,"t":"و در وسط شارع عام آن و بر هر دو کناره نهر، درخت حیات را که دوازده میوه می‌آورد یعنی هر ماه میوه خود رامی دهد؛ و برگهای آن درخت برای شفای امت هامی باشد."},{"v":3,"t":"و دیگر هیچ لعنت نخواهد بود و تخت خدا و بره در آن خواهد بود و بندگانش او راعبادت خواهند نمود."},{"v":4,"t":"و چهره او را خواهنددید و اسم وی بر پیشانی‌ایشان خواهد بود."},{"v":5,"t":"ودیگر شب نخواهد بود و احتیاج به چراغ و نورآفتاب ندارند، زیرا خداوند خدا بر ایشان روشنایی می‌بخشد و تا ابدالاباد سلطنت خواهندکرد."},{"v":6,"t":"و مرا گفت: «این کلام امین و راست است وخداوند خدای ارواح انبیا، فرشته خود را فرستادتا به بندگان خود آنچه را که زود می‌باید واقع شود، نشان دهد.»"},{"v":7,"t":"«و اینک به زودی می‌آیم. خوشابحال کسی‌که کلام نبوت این کتاب را نگاه دارد.»"},{"v":8,"t":"و من، یوحنا، این امور را شنیدم و دیدم وچون شنیدم و دیدم، افتادم تا پیش پایهای آن فرشته‌ای که این امور را به من نشان داد سجده کنم."},{"v":9,"t":"او مرا گفت: «زنهار نکنی، زیرا که همخدمت با تو هستم و با انبیا یعنی برادرانت و باآنانی که کلام این کتاب را نگاه دارند. خدا راسجده کن.»"},{"v":10,"t":"و مرا گفت: «کلام نبوت این کتاب را مهر مکن زیرا که وقت نزدیک است."},{"v":11,"t":"هر‌که ظالم است، باز ظلم کند و هر‌که خبیث است، بازخبیث بماند و هر‌که عادل است، باز عدالت کند وهر‌که مقدس است، باز مقدس بشود.»"},{"v":12,"t":"«و اینک به زودی می‌آیم و اجرت من با من است تا هر کسی را بحسب اعمالش جزا دهم."},{"v":13,"t":"من الف و یاء و ابتدا و انتها و اول و آخر هستم"},{"v":14,"t":"خوشابحال آنانی که رختهای خود رامی شویند تا بر درخت حیات اقتدار یابند و به دروازه های شهر درآیند،"},{"v":15,"t":"زیرا که سگان وجادوگران و زانیان و قاتلان و بت‌پرستان و هر‌که دروغ را دوست دارد و بعمل آورد، بیرون می‌باشند."},{"v":16,"t":"من عیسی فرشته خود را فرستادم تاشما را در کلیساها بدین امور شهادت دهم. من ریشه و نسل داود و ستاره درخشنده صبح هستم.»"},{"v":17,"t":"و روح و عروس می‌گویند: «بیا!» و هر‌که می‌شنود بگوید: «بیا!» و هر‌که تشنه باشد، بیاید وهر‌که خواهش دارد، از آب حیات بی‌قیمت بگیرد."},{"v":18,"t":"زیرا هر کس را که کلام نبوت این کتاب را بشنود، شهادت می‌دهم که اگر کسی بر آنهابیفزاید، خدا بلایای مکتوب در این کتاب را بروی خواهد افزود."},{"v":19,"t":"و هر گاه کسی از کلام این نبوت چیزی کم کند، خدا نصیب او را از درخت حیات و از شهر مقدس و از چیزهایی که در این کتاب نوشته است، منقطع خواهد کرد."},{"v":20,"t":"او که بر این امور شاهد است، می‌گوید: «بلی، به زودی می‌آیم!» آمین. بیا، ای خداوند عیسی!"},{"v":21,"t":"فیض خداوند ما عیسی مسیح با همه شماباد. آمین."}],"en":[{"v":1,"t":"He showed me a river of water of life, clear as crystal, proceeding out of the throne of God and of the Lamb,"},{"v":2,"t":"in the middle of its street. On this side of the river and on that was the tree of life, bearing twelve kinds of fruits, yielding its fruit every month. The leaves of the tree were for the healing of the nations."},{"v":3,"t":"There will be no curse any more. The throne of God and of the Lamb will be in it, and his servants will serve him."},{"v":4,"t":"They will see his face, and his name will be on their foreheads."},{"v":5,"t":"There will be no night, and they need no lamp light or sun light; for the Lord God will illuminate them. They will reign forever and ever."},{"v":6,"t":"He said to me, “These words are faithful and true. The Lord God of the spirits of the prophets sent his angel to show to his bondservants the things which must happen soon.”"},{"v":7,"t":"“Behold, I am coming soon! Blessed is he who keeps the words of the prophecy of this book.”"},{"v":8,"t":"Now I, John, am the one who heard and saw these things. When I heard and saw, I fell down to worship before the feet of the angel who had shown me these things."},{"v":9,"t":"He said to me, “You must not do that! I am a fellow bondservant with you and with your brothers, the prophets, and with those who keep the words of this book. Worship God.”"},{"v":10,"t":"He said to me, “Don’t seal up the words of the prophecy of this book, for the time is at hand."},{"v":11,"t":"He who acts unjustly, let him act unjustly still. He who is filthy, let him be filthy still. He who is righteous, let him do righteousness still. He who is holy, let him be holy still.”"},{"v":12,"t":"“Behold, I am coming soon! My reward is with me, to repay to each man according to his work."},{"v":13,"t":"I am the Alpha and the Omega, the First and the Last, the Beginning and the End."},{"v":14,"t":"Blessed are those who do his commandments, that they may have the right to the tree of life, and may enter in by the gates into the city."},{"v":15,"t":"Outside are the dogs, the sorcerers, the sexually immoral, the murderers, the idolaters, and everyone who loves and practices falsehood."},{"v":16,"t":"I, Jesus, have sent my angel to testify these things to you for the assemblies. I am the root and the offspring of David, the Bright and Morning Star.”"},{"v":17,"t":"The Spirit and the bride say, “Come!” He who hears, let him say, “Come!” He who is thirsty, let him come. He who desires, let him take the water of life freely."},{"v":18,"t":"I testify to everyone who hears the words of the prophecy of this book: if anyone adds to them, God will add to him the plagues which are written in this book."},{"v":19,"t":"If anyone takes away from the words of the book of this prophecy, God will take away his part from the tree of life, and out of the holy city, which are written in this book."},{"v":20,"t":"He who testifies these things says, “Yes, I am coming soon.” Amen! Yes, come, Lord Jesus!"},{"v":21,"t":"The grace of the Lord Jesus Christ be with all the saints. Amen."}],"hr":[{"v":1,"t":"I pokaza mi rijeku vode života, bistru kao prozirac: izvire iz prijestolja Božjeg i Jaganjčeva."},{"v":2,"t":"Posred gradskoga trga, s obje strane rijeke, stablo života što rodi dvanaest puta, svakog mjeseca svoj rod. A lišće stabla za zdravlje je narodima."},{"v":3,"t":"I neće više biti nikakva prokletstva. I prijestolje će Božje i Jaganjčevo biti u gradu i sluge će mu se njegove klanjati"},{"v":4,"t":"i gledati lice njegovo, a ime će im njegovo biti na čelima."},{"v":5,"t":"Noći više biti neće i neće trebati svjetla od svjetiljke ni svjetla sunčeva: obasjavat će ih Gospod Bog i oni će kraljevati u vijeke vjekova."},{"v":6,"t":"I reče mi: “Ove su riječi vjerne i istinite jer Gospod Bog, nadahnitelj proroka, posla svoga anđela da on pokaže slugama njegovim što se ima dogoditi ubrzo."},{"v":7,"t":"I evo, dolazim ubrzo! Blago onomu koji čuva riječi proroštva ove knjige!”"},{"v":8,"t":"Ja, Ivan, čuo sam i vidio sve ovo. I kad sam to vidio i čuo, padoh pred noge anđelu koji mi to pokaza da mu se poklonim."},{"v":9,"t":"A on će mi: “Nipošto! Sluga sam kao i ti i braća tvoja proroci i svi koji čuvaju riječi ove knjige. Bogu se pokloni!”"},{"v":10,"t":"A zatim će mi: “Ne zapečati riječi proroštva ove knjige jer - vrijeme je blizu!"},{"v":11,"t":"Nepravednik neka samo i dalje čini nepravdu! Okaljan neka se i dalje kalja! Pravednik neka i dalje živi pravedno! Svet neka se i dalje posvećuje!”"},{"v":12,"t":"“Evo, dolazim ubrzo i plaća moja sa mnom: naplatit ću svakom po njegovu djelu!”"},{"v":13,"t":"“Ja sam Alfa i Omega, Prvi i Posljednji, Početak i Svršetak!"},{"v":14,"t":"Blago onima koji peru svoje haljine: imat će pravo na stablo života i na vrata će smjeti u grad!"},{"v":15,"t":"Vani pak ostaju psi i vračari, bludnice, ubojice i idolopoklonici i tko god ljubi i čini laž.”"},{"v":16,"t":"“Ja, Isus, poslah anđela svoga posvjedočiti ovo po crkvama. Ja sam korijen i izdanak Davidov, sjajna zvijezda Danica.”"},{"v":17,"t":"I Duh i Zaručnica govore: “Dođi!” I tko ovo čuje, neka rekne: “Dođi!” Tko je žedan, neka dođe; tko hoće, neka zahvati vode života zabadava!"},{"v":18,"t":"Ja svjedočim svakomu tko sluša riječi proroštva u ovoj knjizi: Tko ovomu što doda, Bog će njemu dodati zla napisana u ovoj knjizi."},{"v":19,"t":"I tko oduzme od riječi proroštva u ovoj knjizi, Bog će mu oduzeti udio na stablu života i na svetom gradu - na svemu što je napisano u ovoj knjizi."},{"v":20,"t":"Svjedok za sve ovo govori: “Da, dolazim ubrzo!” Amen! Dođi, Gospodine Isuse!"},{"v":21,"t":"Milost Gospodina Isusa sa svima!"}]}}},"keyTerms":{"JHN.3.16":[{"term":{"fa":"محبت نمود","en":"loved","hr":"ljubio"},"original":"ἠγάπησεν / agapaō","pronunciation":{"fa":"اَگاپائو / اِگاپِسِن","en":"agapao / ēgapēsen","hr":"agapao / ēgapēsen"},"meaning":{"fa":"محبت عهدی و ارادی خدا؛ محبتی که فقط احساس نیست، بلکه خود را در بخشش و عمل نجات‌بخش آشکار می‌کند.","en":"Covenant, willing love; not mere emotion, but love revealed through giving and saving action.","hr":"Savezna, voljna ljubav; nije samo osjećaj, nego ljubav otkrivena kroz davanje i spasiteljsko djelo."}},{"term":{"fa":"حیات جاودانی","en":"eternal life","hr":"život vječni"},"original":"ζωὴ αἰώνιος / zōē aiōnios","pronunciation":{"fa":"زوئه آیونیوس","en":"zōē aiōnios","hr":"zōē aiōnios"},"meaning":{"fa":"زندگی از نوع الهی؛ فقط طولانی بودن زندگی نیست، بلکه مشارکت در حیات خدا در مسیح است.","en":"The life of God’s kind; not merely endless duration, but participation in God’s life in Christ.","hr":"Život Božje vrste; ne samo beskrajno trajanje, nego sudjelovanje u Božjem životu u Kristu."}}],"JHN.1.1":[{"term":{"fa":"کلمه","en":"Word","hr":"Riječ"},"original":"λόγος / logos","pronunciation":{"fa":"لوگوس","en":"logos","hr":"logos"},"meaning":{"fa":"بیان کامل، عقل و آشکارسازی خدا؛ در یوحنا، لوگوس شخصی است و به مسیح ازلی اشاره دارد.","en":"God’s full expression, reason, and self-revelation; in John, Logos is personal and points to the eternal Christ.","hr":"Božji puni izraz, razum i samoobjava; kod Ivana Logos je osoban i upućuje na vječnog Krista."}}],"ROM.3.24":[{"term":{"fa":"عادل شمرده شدن","en":"justified","hr":"opravdani"},"original":"δικαιόω / dikaioō","pronunciation":{"fa":"دیکایوئو","en":"dikaioō","hr":"dikaioō"},"meaning":{"fa":"اعلام عادل بودن در دادگاه الهی؛ خدا بر اساس کار مسیح، ایماندار را عادل اعلام می‌کند، نه بر اساس شایستگی انسانی.","en":"To be declared righteous in God’s court; based on Christ’s work, not human merit.","hr":"Biti proglašen pravednim pred Bogom; na temelju Kristova djela, a ne ljudske zasluge."}},{"term":{"fa":"فیض","en":"grace","hr":"milost"},"original":"χάρις / charis","pronunciation":{"fa":"خاریس","en":"charis","hr":"charis"},"meaning":{"fa":"لطف و عطای بی‌استحقاق خدا که نجات، قدرت و جایگاه تازه را در مسیح می‌بخشد.","en":"God’s undeserved favor and gift that gives salvation, power, and a new standing in Christ.","hr":"Nezaslužena Božja naklonost i dar koji daje spasenje, snagu i novi položaj u Kristu."}}],"ROM.5.1":[{"term":{"fa":"سلامتی","en":"peace","hr":"mir"},"original":"εἰρήνη / eirēnē","pronunciation":{"fa":"ایرِینه","en":"eirēnē","hr":"eirēnē"},"meaning":{"fa":"آشتی و آرامش حاصل از رابطه درست با خدا؛ فقط احساس آرامش نیست، بلکه وضعیت صلح با خداست.","en":"Reconciliation and wholeness from a right relationship with God; not only a feeling, but a state of peace with God.","hr":"Pomirenje i cjelovitost iz ispravnog odnosa s Bogom; ne samo osjećaj, nego stanje mira s Bogom."}}],"ROM.8.1":[{"term":{"fa":"محکومیت","en":"condemnation","hr":"osude"},"original":"κατάκριμα / katakrima","pronunciation":{"fa":"کاتاکریما","en":"katakrima","hr":"katakrima"},"meaning":{"fa":"حکم محکومیت و مجازات؛ در مسیح، این حکم بر ایماندار باقی نمی‌ماند.","en":"A sentence of condemnation and penalty; in Christ, this verdict no longer remains over the believer.","hr":"Presuda osude i kazne; u Kristu ta presuda više ne ostaje nad vjernikom."}}],"ROM.8.14":[{"term":{"fa":"هدایت می‌شوند","en":"led","hr":"vođeni"},"original":"ἄγονται / agontai","pronunciation":{"fa":"آگونتای","en":"agontai","hr":"agontai"},"meaning":{"fa":"هدایت پیوسته توسط روح خدا؛ زندگی فرزندان خدا فقط با قانون بیرونی نیست، بلکه با رهبری روح‌القدس است.","en":"Ongoing guidance by the Spirit of God; God’s children live not merely by outward rule, but by the Spirit’s leading.","hr":"Stalno vodstvo Božjim Duhom; Božja djeca ne žive samo po vanjskom pravilu, nego po vodstvu Duha."}}],"EPH.2.8":[{"term":{"fa":"فیض","en":"grace","hr":"milost"},"original":"χάρις / charis","pronunciation":{"fa":"خاریس","en":"charis","hr":"charis"},"meaning":{"fa":"نجات عطای خداست، نه نتیجه تلاش انسانی؛ فیض آغاز، قدرت و امنیت نجات را از خدا می‌داند.","en":"Salvation is God’s gift, not the result of human effort; grace makes God the source, power, and security of salvation.","hr":"Spasenje je Božji dar, ne rezultat ljudskog napora; milost pokazuje Boga kao izvor, snagu i sigurnost spasenja."}},{"term":{"fa":"ایمان","en":"faith","hr":"vjera"},"original":"πίστις / pistis","pronunciation":{"fa":"پیستیس","en":"pistis","hr":"pistis"},"meaning":{"fa":"اعتماد قلبی و تکیه بر خدا و کلام او؛ فقط قبول ذهنی نیست، بلکه اتکا و پاسخ به حقیقت خداست.","en":"Heart trust and reliance on God and His Word; not mere mental agreement, but dependence and response to God’s truth.","hr":"Pouzdanje srca i oslanjanje na Boga i Njegovu riječ; ne samo mentalno slaganje, nego ovisnost i odgovor na Božju istinu."}}],"HEB.11.1":[{"term":{"fa":"ایمان","en":"faith","hr":"vjera"},"original":"πίστις / pistis","pronunciation":{"fa":"پیستیس","en":"pistis","hr":"pistis"},"meaning":{"fa":"یقین و اعتماد فعال به واقعیت‌های خدا؛ ایمان، حقیقت نادیده را برای قلب ایماندار واقعی و قابل اتکا می‌سازد.","en":"Active assurance and trust in God’s realities; faith makes the unseen truth real and reliable to the believer’s heart.","hr":"Aktivna sigurnost i pouzdanje u Božje stvarnosti; vjera čini nevidljivu istinu stvarnom i pouzdanom srcu vjernika."}}],"1JN.4.8":[{"term":{"fa":"محبت","en":"love","hr":"ljubav"},"original":"ἀγάπη / agapē","pronunciation":{"fa":"اَگاپه","en":"agapē","hr":"agapē"},"meaning":{"fa":"محبت از ذات خدا سرچشمه می‌گیرد؛ این محبت ارادی، بخشنده و عهدی است، نه صرفاً عاطفه انسانی.","en":"Love flows from God’s nature; it is willing, giving, and covenantal, not merely human emotion.","hr":"Ljubav izvire iz Božje naravi; ona je voljna, darujuća i savezna, ne samo ljudska emocija."}}]}};
